window.BOOK={"slug": "ezekiel", "name": "Ezekiel", "testament": "OT", "orig_label": "Hebrew · WLC", "rtl": true, "translations": [{"id": "kjv", "label": "KJV (1611)"}, {"id": "web", "label": "WEB (modern)"}, {"id": "bsb", "label": "Berean Standard"}, {"id": "asv", "label": "ASV (1901)"}, {"id": "ylt", "label": "Young's Literal"}, {"id": "dra", "label": "Douay-Rheims"}, {"id": "bbe", "label": "Basic English"}, {"id": "geneva", "label": "Geneva (1599)"}, {"id": "wycliffe", "label": "Wycliffe (1382)"}, {"id": "rotherham", "label": "Rotherham Emph."}, {"id": "darby", "label": "Darby"}, {"id": "twenty", "label": "20th Century NT"}, {"id": "jps", "label": "JPS Tanakh (1917)"}, {"id": "acv", "label": "A Conservative Version"}, {"id": "anderson", "label": "Anderson NT (1864)"}, {"id": "haweis", "label": "Haweis NT (1795)"}, {"id": "noyes", "label": "Noyes NT (1869)"}, {"id": "webster", "label": "Webster (1833)"}, {"id": "vulgate", "label": "Vulgate · Latin"}, {"id": "brenton", "label": "LXX · Brenton (Eng)"}], "books": [{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}], "chapters": [{"c": 1, "verses": [{"v": 1, "ref": "1:1", "o": "וַ/יְהִ֣י בִּ/שְׁלֹשִׁ֣ים שָׁנָ֗ה בָּֽ/רְבִיעִי֙ בַּ/חֲמִשָּׁ֣ה לַ/חֹ֔דֶשׁ וַ/אֲנִ֥י בְ/תֽוֹךְ הַ/גּוֹלָ֖ה עַל נְהַר כְּבָ֑ר נִפְתְּחוּ֙ הַ/שָּׁמַ֔יִם וָ/אֶרְאֶ֖ה מַרְא֥וֹת אֱלֹהִֽים", "en": {"kjv": "Now it came to pass in the thirtieth year, in the fourth month, in the fifth day of the month, as I was among the captives by the river of Chebar, that the heavens were opened, and I saw visions of God.", "web": "Now in the thirtieth year, in the fourth month, in the fifth of the month, as I was among the captives by the river Chebar, the heavens were opened, and I saw visions of God.", "bsb": "In the thirtieth year, on the fifth day of the fourth month, while I was among the exiles by the River Kebar, the heavens opened and I saw visions of God.", "asv": "Now it came to pass in the thirtieth year, in the fourthmonth, in the fifthdayof the month, as I was among the captives by the river Chebar, that the heavens were opened, and I saw visions of God.", "ylt": "And it cometh to pass, in the thirtieth year, in the fourth month , in the fifth of the month, and I am in the midst of the Removed by the river Chebar, the heavens have been opened, and I see visions of God.", "dra": "Now it came to pass in the thirtieth year, in the fourth month, on the fifth day of the month, when I was in the midst of the captives by the river Chobar, the heavens were opened, and I saw the visions of God.", "bbe": "Now it came about in the thirtieth year, in the fourth month, on the fifth day of the month, while I was by the river Chebar among those who had been made prisoners, that the heavens were made open and I saw visions of God.", "geneva": "It came to passe in the thirtieth yere in the fourth moneth, and in the fift day of the moneth (as I was among the captiues by the riuer Chebar) that the heauens were opened and I sawe visions of GOD.", "wycliffe": "And it was don, in the thrittithe yeer, in the fourthe monethe, in the fyuethe dai of the moneth, whanne Y was in the myddis of caitifs, bisidis the flood Chobar, heuenes weren openyd, and Y siy the reuelaciouns of God.", "rotherham": "And it came to pass in the thirtieth year, in the fourth month on the fifth day of the month I being in the midst of them of the captivity, by the river Chebar, that the heavens were opened, and I saw visions of God.", "darby": "Now it came to pass in the thirtieth year, in the fourth [month], on the fifth of the month, as I was among the captives by the river Chebar, the heavens were opened, and I saw visions ofGod.", "twenty": "", "jps": "NOW IT came to pass in the thirtieth year, in the fourth month, in the fifth day of the month, as I was among the captives by the river Chebar that the heavens were opened, and I saw visions of G-d.", "acv": "Now it came to pass in the thirtieth year, in the fourth month, in the fifth day of the month, as I was among the captives by the river Chebar, that the heavens were opened, and I saw visions of God.", "anderson": "", "haweis": "", "noyes": "Now it came to pass in the thirtieth year, in the fourth month, in the fifth day of the month, as I was among the captives by the river Chebar, that the heavens were opened, and I saw visions of God.", "webster": "Now it came to pass in the thirtieth year, in the fourth [month], in the fifth [day] of the month, as I [was] among the captives by the river of Kebar, [that] the heavens were opened, and I saw visions of God.", "vulgate": "et factum est in tricesimo anno in quarto mense in quinta mensis cum essem in medio captivorum iuxta fluvium Chobar aperti sunt caeli et vidi visiones Dei;", "brenton": "Now it came to pass in the thirtieth year, in the fourth month, on the fifth day of the month, that I was in the midst of the captivity by the river of Chobar; and the heavens were opened, and I saw visions of God."}}, {"v": 2, "ref": "1:2", "o": "בַּ/חֲמִשָּׁ֖ה לַ/חֹ֑דֶשׁ הִ֚יא הַ/שָּׁנָ֣ה הַ/חֲמִישִׁ֔ית לְ/גָל֖וּת הַ/מֶּ֥לֶךְ יוֹיָכִֽין", "en": {"kjv": "In the fifth day of the month, which was the fifth year of king Jehoiachin’s captivity,", "web": "In the fifth of the month, which was the fifth year of king Jehoiachin’s captivity,", "bsb": "On the fifth day of the month—it was the fifth year of the exile of King Jehoiachin—", "asv": "In the fifthdayof the month, which was the fifth year of king Jehoiachin’s captivity,", "ylt": "In the fifth of the month--it is the fifth year of the removal of the king Jehoiachin--", "dra": "On the fifth day of the month, the same was the fifth year of the captivity of king Joachin,", "bbe": "On the fifth day of the month, in the fifth year after King Jehoiachin had been made a prisoner,", "geneva": "In the fift day of the moneth (which was the fift yere of King Ioiachins captiuitie)", "wycliffe": "In the fyueth dai of the monethe; thilke is the fyuethe yeer of passing ouer of Joachym, kyng of Juda;", "rotherham": "On the fifth of the month, that was the fifth year of the captivity of King Jehoiachin,", "darby": "On the fifth of the month, (it was the fifth year of king Jehoiachin's captivity,)", "twenty": "", "jps": "In the fifth day of the month, which was the fifth year of king Jehoiachin's captivity,", "acv": "In the fifth day of the month, which was the fifth year of king Jehoiachin's captivity,", "anderson": "", "haweis": "", "noyes": "On the fifth day of the month, in the fifth year of the captivity of King Jehoiachin,", "webster": "In the fifth [day] of the month, which [was] the fifth year of king Jehoiachin's captivity,", "vulgate": "in quinta mensis ipse est annus quintus transmigrationis regis Ioachin;", "brenton": "On the fifth day of the month; this was the fifth year of the captivity of king Joakim."}}, {"v": 3, "ref": "1:3", "o": "הָיֹ֣ה הָיָ֣ה דְבַר יְ֠הוָה אֶל יְחֶזְקֵ֨אל בֶּן בּוּזִ֧י הַ/כֹּהֵ֛ן בְּ/אֶ֥רֶץ כַּשְׂדִּ֖ים עַל נְהַר כְּבָ֑ר וַ/תְּהִ֥י עָלָ֛י/ו שָׁ֖ם יַד יְהוָֽה", "en": {"kjv": "The word of the Lord came expressly unto Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of the Lord was there upon him.", "web": "Yahweh’s word came expressly to Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of Yahweh was there on him.", "bsb": "the word of the LORD came directly to Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the River Kebar. And there the LORD’s hand was upon him.", "asv": "the word of Jehovah came expressly unto Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of Jehovah was there upon him.", "ylt": "hath the word of Jehovah certainly been unto Ezekiel son of Buzi the priest, in the land of the Chaldeans, by the river Chebar, and there is on him there a hand of Jehovah.", "dra": "The word of the Lord came to Ezekiel the priest the son of Buzi in the land of the Chaldeans, by the river Chobar: and the hand of the Lord was there upon him.", "bbe": "The word of the Lord came to me, Ezekiel the priest, the son of Buzi, in the land of the Chaldaeans by the river Chebar; and the hand of the Lord was on me there.", "geneva": "The word of the Lord came vnto Ezekiel the Priest, the sonne of Buzi, in the lande of the Caldeans, by the riuer Chebar, where the hande of the Lord was vpon him.", "wycliffe": "the word of the Lord was maad to Ezechiel, preest, the sone of Busi, in the lond of Caldeis, bisidis the flood Chobar; and the hond of the Lord was maad there on hym.", "rotherham": "in very deed came the word of Yahweh unto Ezekiel son of Buzi the priest in the land of the Chaldeans by the river Chebar,—yea the hand of Yahweh, came on him there.", "darby": "the word of Jehovah came expressly unto Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of Jehovah was there upon him.", "twenty": "", "jps": "the word of HaShem came expressly unto Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of HaShem was there upon him.", "acv": "the word of Jehovah came expressly to Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar, and the hand of Jehovah was there upon him.", "anderson": "", "haweis": "", "noyes": "the word of Jehovah came to Ezekiel, the son of Buzi, the priest, in the land of the Chaldaeans, by the river Chebar; and the hand of Jehovah was there upon him.", "webster": "The word of the LORD came expressly to Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Kebar; and the hand of the LORD was there upon him.", "vulgate": "factum est verbum Domini ad Hiezecihel filium Buzi sacerdotem in terra Chaldeorum secus flumen Chobar et facta est super eum ibi manus Domini;", "brenton": "And the word of the Lord came to Jezekiel the priest, the son of Buzi, in the land of the Chaldeans, by the river of Chobar; and the hand of the Lord was upon me."}}, {"v": 4, "ref": "1:4", "o": "וָ/אֵ֡רֶא וְ/הִנֵּה֩ ר֨וּחַ סְעָרָ֜ה בָּאָ֣ה מִן הַ/צָּפ֗וֹן עָנָ֤ן גָּדוֹל֙ וְ/אֵ֣שׁ מִתְלַקַּ֔חַת וְ/נֹ֥גַֽהּ ל֖/וֹ סָבִ֑יב וּ/מִ֨/תּוֹכָ֔/הּ כְּ/עֵ֥ין הַ/חַשְׁמַ֖ל מִ/תּ֥וֹךְ הָ/אֵֽשׁ", "en": {"kjv": "And I looked, and, behold, a whirlwind came out of the north, a great cloud, and a fire infolding itself, and a brightness was about it, and out of the midst thereof as the colour of amber, out of the midst of the fire.", "web": "I looked, and behold, a stormy wind came out of the north, a great cloud, with flashing lightning, and a brightness around it, and out of its midst as it were glowing metal, out of the midst of the fire.", "bsb": "I looked and saw a whirlwind coming from the north, a great cloud with fire flashing back and forth and brilliant light all around it. In the center of the fire was a gleam like amber,", "asv": "And I looked, and, behold, a stormy wind came out of the north, a great cloud, with a fire infolding itself, and a brightness round about it, and out of the midst thereof as it were glowing metal, out of the midst of the fire.", "ylt": "And I look, and lo, a tempestuous wind is coming from the north, a great cloud, and fire catching itself, and brightness to it round about, and out of its midst as the colour of copper, out of the midst of the fire.", "dra": "And I saw, and behold a whirlwind came out of the north: and a great cloud, and a fire infolding it, and brightness was about it: and out of the midst thereof, that is, out of the midst of the fire, as it were the resemblance of amber:", "bbe": "And, looking, I saw a storm-wind coming out of the north, a great cloud with flames of fire coming after one another, and a bright light shining round about it and in the heart of it was something coloured like electrum.", "geneva": "And I looked, and beholde, a whirlewinde came out of the North, a great cloude and a fire wrapped about it, and a brightnesse was about it, and in the middes thereof, to wit, in the middes of the fire came out as the likenesse of amber.", "wycliffe": "And Y siy, and lo! a whirlewynd cam fro the north, and a greet cloude, and fier wlappynge in, and briytnesse in the cumpas therof; and as the licnesse of electre fro the myddis therof, that is, fro the myddis of the fier.", "rotherham": "So then I beheld and lo! a tempestuous wind coming out of the North, a great cloud and a fire catching hold of itself, and it had a brightness round about,—and out of the midst thereof, as burnished copper to look upon out of the midst of the fire;", "darby": "And I looked, and behold, a stormy wind came out of the north, a great cloud, and a fire infolding itself, and a brightness was about it, and out of the midst thereof as the look of glowing brass, out of the midst of the fire.", "twenty": "", "jps": "And I looked, and, behold, a stormy wind came out of the north, a great cloud, with a fire flashing up, so that a brightness was round about it; and out of the midst thereof as the colour of electrum, out of the midst of the fire.", "acv": "And I looked, and, behold, a stormy wind came out of the north, a great cloud, with a fire enfolding itself, and a brightness round about it, and out of the midst of it, as it were glowing metal, out of the midst of the fire.", "anderson": "", "haweis": "", "noyes": "And I looked, and behold, a stormy wind came from the north, a great cloud, and a mass of fire; and a brightness was round about it, and in the midst of it the appearance of bright brass, in the midst of the fire.", "webster": "And I looked, and behold, a whirlwind came out of the north, a great cloud, and a fire infolding itself, and a brightness [was] about it, and from the midst of it as the color of amber, from the midst of the fire.", "vulgate": "et vidi et ecce ventus turbinis veniebat ab aquilone et nubes magna et ignis involvens et splendor in circuitu eius et de medio eius quasi species electri id est de medio ignis;", "brenton": "And I looked, and, behold, a sweeping wind came from the north, and a great cloud on it, and there was brightness round about it, and gleaming fire, and in the midst of it as it were the appearance of amber in the midst of the fire, and brightness in it."}}, {"v": 5, "ref": "1:5", "o": "וּ/מִ֨/תּוֹכָ֔/הּ דְּמ֖וּת אַרְבַּ֣ע חַיּ֑וֹת וְ/זֶה֙ מַרְאֵֽי/הֶ֔ן דְּמ֥וּת אָדָ֖ם לָ/הֵֽנָּה", "en": {"kjv": "Also out of the midst thereof came the likeness of four living creatures. And this was their appearance; they had the likeness of a man.", "web": "Out of its midst came the likeness of four living creatures. This was their appearance: they had the likeness of a man.", "bsb": "and within it was the form of four living creatures. And this was their appearance: They had a human form,", "asv": "And out of the midst thereof came the likeness of four living creatures. And this was their appearance: they had the likeness of a man;", "ylt": "And out of its midst is a likeness of four living creatures, and this is their appearance; a likeness of man is to them,", "dra": "And in the midst thereof the likeness of four living creatures: and this was their appearance: there was the likeness of a man in them.", "bbe": "And in the heart of it were the forms of four living beings. And this was what they were like; they had the form of a man.", "geneva": "Also out of the middes therof came the likenesse of foure beastes, and this was their forme: they had the appearance of a man.", "wycliffe": "And of myddis therof was a licnesse of foure beestis. And this was the biholdyng of tho, the licnesse of a man in tho.", "rotherham": "and out of the midst thereof, a likeness of four living ones, and this was their appearance, the likeness of a man, had they;", "darby": "Also out of the midst thereof, the likeness of four living creatures. And this was their appearance: they had the likeness of a man.", "twenty": "", "jps": "And out of the midst thereof came the likeness of four living creatures. And this was their appearance: they had the likeness of a man.", "acv": "And out of the midst of it came the likeness of four living creatures. And this was their appearance. They had the likeness of a man.", "anderson": "", "haweis": "", "noyes": "And in the midst of it were the forms of four living creatures. And this was their appearance. They had the form of a man.", "webster": "Also from the midst of it [came] the likeness of four living creatures. And this [was] their appearance; they had the likeness of a man.", "vulgate": "et ex medio eorum similitudo quattuor animalium et hic aspectus eorum similitudo hominis in eis;", "brenton": "And in the midst as it were the likeness of four living creatures. And this was their appearance; the likeness of a man was upon them."}}, {"v": 6, "ref": "1:6", "o": "וְ/אַרְבָּעָ֥ה פָנִ֖ים לְ/אֶחָ֑ת וְ/אַרְבַּ֥ע כְּנָפַ֖יִם לְ/אַחַ֥ת לָ/הֶֽם", "en": {"kjv": "And every one had four faces, and every one had four wings.", "web": "Everyone had four faces, and each one of them had four wings.", "bsb": "but each had four faces and four wings.", "asv": "and every one had four faces, and every one of them had four wings.", "ylt": "and four faces are to each, and four wings are to each of them,", "dra": "Every one had four faces, and every one four wings.", "bbe": "And every one had four faces, and every one of them had four wings.", "geneva": "And euery one had foure faces, and euery one had foure wings.", "wycliffe": "And foure faces weren to oon, and foure wyngis weren to oon.", "rotherham": "and four faces each, and four wings each, had they;", "darby": "And every one had four faces, and every one of them had four wings.", "twenty": "", "jps": "And every one had four faces, and every one of them had four wings.", "acv": "And each one had four faces, and each one of them had four wings.", "anderson": "", "haweis": "", "noyes": "And every one had four faces, and every one had four wings.", "webster": "And every one had four faces, and every one had four wings.", "vulgate": "et quattuor facies uni et quattuor pinnae uni;", "brenton": "And each one had four faces, and each one had four wings."}}, {"v": 7, "ref": "1:7", "o": "וְ/רַגְלֵי/הֶ֖ם רֶ֣גֶל יְשָׁרָ֑ה וְ/כַ֣ף רַגְלֵי/הֶ֗ם כְּ/כַף֙ רֶ֣גֶל עֵ֔גֶל וְ/נֹ֣צְצִ֔ים כְּ/עֵ֖ין נְחֹ֥שֶׁת קָלָֽל", "en": {"kjv": "And their feet were straight feet; and the sole of their feet was like the sole of a calf’s foot: and they sparkled like the colour of burnished brass.", "web": "Their feet were straight feet; and the sole of their feet was like the sole of a calf’s foot; and they sparkled like burnished brass.", "bsb": "Their legs were straight, and the soles of their feet were like the hooves of a calf, gleaming like polished bronze.", "asv": "And their feet were straight feet; and the sole of their feet was like the sole of a calf’s foot; and they sparkled like burnished brass.", "ylt": "and their feet are straight feet, and the sole of their feet is as a sole of a calf's foot, and they are sparkling as the colour of bright brass;", "dra": "Their feet were straight feet, and the sole of their foot was like the sole of a calf's foot, and they sparkled like the appearance of glowing brass.", "bbe": "And their feet were straight feet; and the under sides of their feet were like the feet of oxen; and they were shining like polished brass.", "geneva": "And their feete were streight feete, and the sole of their feete was like the sole of a calues foote, and they sparkled like the appearance of bright brasse.", "wycliffe": "And the feet of tho weren streiyt feet, and the soole of the foote of tho was as the soole of a foot of a calf, and sparclis, as the biholdynge of buylynge bras.", "rotherham": "and their feet were straight feet,—and the sole of their feet was like the sole of the foot of a calf, but sparkling, as shining bronze to look upon;", "darby": "And their feet were straight feet; and the sole of their feet was like the sole of a calf's foot; and they sparkled as the look of burnished brass.", "twenty": "", "jps": "And their feet were straight feet; and the sole of their feet was like the sole of a calf's foot; and they sparkled like the colour of burnished brass.", "acv": "And their feet were straight feet, and the sole of their feet was like the sole of a calf's foot, and they sparkled like burnished brass.", "anderson": "", "haweis": "", "noyes": "And their feet were upright; and the sole of their feet was as the sole of a calf’s foot; and they sparkled like polished brass.", "webster": "And their feet [were] straight feet; and the sole of their feet [was] like the sole of a calf's foot: and they sparkled like the color of burnished brass.", "vulgate": "et pedes eorum pedes recti et planta pedis eorum quasi planta pedis vituli et scintillae quasi aspectus aeris candentis;", "brenton": "And their legs were straight; and their feet were winged, and there were sparks, like gleaming brass, and their wings were light."}}, {"v": 8, "ref": "1:8", "o": "ו/יד/ו וִ/ידֵ֣י אָדָ֗ם מִ/תַּ֨חַת֙ כַּנְפֵי/הֶ֔ם עַ֖ל אַרְבַּ֣עַת רִבְעֵי/הֶ֑ם וּ/פְנֵי/הֶ֥ם וְ/כַנְפֵי/הֶ֖ם לְ/אַרְבַּעְתָּֽ/ם", "en": {"kjv": "And they had the hands of a man under their wings on their four sides; and they four had their faces and their wings.", "web": "They had the hands of a man under their wings on their four sides; and the four of them had their faces and their wings thus:", "bsb": "Under their wings on their four sides they had human hands. All four living creatures had faces and wings,", "asv": "And they had the hands of a man under their wings on their four sides; and they four had their faces and their wings thus:", "ylt": "and hands of man under their wings--on their four sides, and their faces and their wings-- are to them four;", "dra": "And they had the hands of a man under their wings on their four sides: and they had faces, and wings on the four sides,", "bbe": "And they had the hands of a man under their wings; the four of them had faces on their four sides.", "geneva": "And the handes of a man came out from vnder their wings in the foure parts of them, and they foure had their faces, and their wings.", "wycliffe": "And the hondis of a man weren vndur the wyngis of tho, in foure partis. And tho hadden faces and wyngis bi foure partis;", "rotherham": "and the hands of a man! were under their wings, on their four sides,—and their faces and their wings belonged to the four of them:", "darby": "And they had the hands of a man under their wings on their four sides; and they four had their faces and their wings:", "twenty": "", "jps": "And they had the hands of a man under their wings on their four sides; and as for the faces and wings of them four,", "acv": "And they had the hands of a man under their wings on their four sides. And those four had their faces and their wings thus:", "anderson": "", "haweis": "", "noyes": "And they had the hands of a man under their wings on their four sides, and all four had faces and wings.", "webster": "And [they had] the hands of a man under their wings on their four sides; and they four had their faces and their wings.", "vulgate": "et manus hominis sub pinnis eorum in quattuor partibus et facies et pinnas per quattuor partes habebant;", "brenton": "And the hand of a man was under their wings on their four sides."}}, {"v": 9, "ref": "1:9", "o": "חֹֽבְרֹ֛ת אִשָּׁ֥ה אֶל אֲחוֹתָ֖/הּ כַּנְפֵי/הֶ֑ם לֹא יִסַּ֣בּוּ בְ/לֶכְתָּ֔/ן אִ֛ישׁ אֶל עֵ֥בֶר פָּנָ֖י/ו יֵלֵֽכוּ", "en": {"kjv": "Their wings were joined one to another; they turned not when they went; they went every one straight forward.", "web": "their wings were joined one to another; they didn’t turn when they went; each one went straight forward.", "bsb": "and their wings were touching one another. They did not turn as they moved; each one went straight ahead.", "asv": "their wings were joined one to another; they turned not when they went; they went every one straight forward.", "ylt": "joining one unto another are their wings, they turn not round in their going, each straight forward they go.", "dra": "And the wings of one were joined to the wings of another. They turned not when they went: but every one went straight forward.", "bbe": "They went without turning, every one went straight forward.", "geneva": "They where ioyned by their wings one to another, and when they went forth, they returned not, but euery one went streight forward.", "wycliffe": "and the wyngis of tho weren ioyned togidir of oon to another. Tho turneden not ayen, whanne tho yeden, but eche yede bifore his face.", "rotherham": "joined to each other, were their wings,—they turned not when they went, each one straight before him, did they go;", "darby": "their wings were joined one to another; they turned not when they went; they went every one straight forward.", "twenty": "", "jps": "their wings were joined one to another; they turned not when they went; they went every one straight forward.", "acv": "Their wings were joined one to another. They did not turn when they went; they went each one straight forward.", "anderson": "", "haweis": "", "noyes": "Their wings were joined one to another; they turned not about when they went; they went every one straight forward.", "webster": "Their wings [were] joined one to another; they turned not when they went; they went every one straight forward.", "vulgate": "iunctaeque erant pinnae eorum alterius ad alterum non revertebantur cum incederent sed unumquodque ante faciem suam gradiebatur;", "brenton": "And the faces of them four turned not when they went; they went everyone straight forward."}}, {"v": 10, "ref": "1:10", "o": "וּ/דְמ֣וּת פְּנֵי/הֶם֮ פְּנֵ֣י אָדָם֒ וּ/פְנֵ֨י אַרְיֵ֤ה אֶל הַ/יָּמִין֙ לְ/אַרְבַּעְתָּ֔/ם וּ/פְנֵי שׁ֥וֹר מֵֽ/הַ/שְּׂמֹ֖אול לְ/אַרְבַּעְתָּ֑/ן וּ/פְנֵי נֶ֖שֶׁר לְ/אַרְבַּעְתָּֽ/ן", "en": {"kjv": "As for the likeness of their faces, they four had the face of a man, and the face of a lion, on the right side: and they four had the face of an ox on the left side; they four also had the face of an eagle.", "web": "As for the likeness of their faces, they had the face of a man; and the four of them had the face of a lion on the right side; and the four of them had the face of an ox on the left side; the four of them also had the face of an eagle.", "bsb": "The form of their faces was that of a man, and each of the four had the face of a lion on the right side, the face of an ox on the left side, and also the face of an eagle.", "asv": "As for the likeness of their faces, they had the face of a man; and they four had the face of a lion on the right side; and they four had the face of an ox on the left side; they four had also the face of an eagle.", "ylt": "As to the likeness of their faces, the face of a man, and the face of a lion, toward the right are to them four, and the face of an ox on the left are to them four, and the face of an eagle are to them four.", "dra": "And as for the likeness of their faces: there was the face of a man, and the face of a lion on the right side of all the four: and the face of an ox, on the left side of all the four: and the face of an eagle over all the four.", "bbe": "As for the form of their faces, they had the face of a man, and the four of them had the face of a lion on the right side, and the four of them had the face of an ox on the left side, and the four of them had the face of an eagle.", "geneva": "And the similitude of their faces was as the face of a man: and they foure had the face of a lyon on the right side, and they foure had the face of a bullocke on the left side: they foure also had the face of an eagle.", "wycliffe": "Forsothe the licnesse `of the face of tho was the face of a man and the face of a lioun at the riythalf of tho foure. Forsothe the face of an oxe was at the left half of tho foure; and the face of an egle was aboue tho foure.", "rotherham": "and the likeness of their faces was the face of a man, with the face of a lion to the right of the four of them, and the face of an ox on the left, of the four of them,—the face of an eagle, also had they four;", "darby": "And the likeness of their faces was the face of a man; and they four had the face of a lion on the right side; and they four had the face of an ox on the left side; they four had also the face of an eagle.", "twenty": "", "jps": "As for the likeness of their faces, they had the face of a man; and they four had the face of a lion on the right side; and they four had the face of an ox on the left side; they four had also the face of an eagle.", "acv": "As for the likeness of their faces, they had the face of a man. And those four had the face of a lion on the right side, and those four had the face of an ox on the left side, those four also had the face of an eagle.", "anderson": "", "haweis": "", "noyes": "As for the form of their faces, all four had the face of a man, and the face of a lion on the right side, and all four had the face of an ox on the left side, and all four had also the face of an eagle.", "webster": "As for the likeness of their faces, they four had the face of a man and the face of a lion, on the right side: and they four had the face of an ox on the left side; they four also had the face of an eagle.", "vulgate": "similitudo autem vultus eorum facies hominis et facies leonis a dextris ipsorum quattuor facies autem bovis a sinistris ipsorum quattuor et facies aquilae ipsorum quattuor;", "brenton": "And the likeness of their faces was the face of a man, and the face of a lion on the right of the four; and the face of a calf on the left of the four; and the face of an eagle to the four."}}, {"v": 11, "ref": "1:11", "o": "וּ/פְנֵי/הֶ֕ם וְ/כַנְפֵי/הֶ֥ם פְּרֻד֖וֹת מִ/לְ/מָ֑עְלָ/ה לְ/אִ֗ישׁ שְׁ֚תַּיִם חֹבְר֣וֹת אִ֔ישׁ וּ/שְׁתַּ֣יִם מְכַסּ֔וֹת אֵ֖ת גְּוִיֹתֵי/הֶֽנָה", "en": {"kjv": "Thus were their faces: and their wings were stretched upward; two wings of every one were joined one to another, and two covered their bodies.", "web": "Such were their faces. Their wings were spread out above. Two wings of each one touched another, and two covered their bodies.", "bsb": "Such were their faces. Their wings were spread upward; each had two wings touching the wings of the creature on either side, and two wings covering its body.", "asv": "And their faces and their wings were separate above; two wings of every one were joined one to another, and two covered their bodies.", "ylt": "And their faces and their wings are separate from above, to each are two joining together, and two are covering their bodies.", "dra": "And their faces, and their wings were stretched upward: two wings of every one were joined, and two covered their bodies:", "bbe": "And their wings were separate at the top; two of the wings of every one were joined one to another, and two were covering their bodies.", "geneva": "Thus were their faces: but their wings were spred out aboue: two wings of euery one were ioined one to another, and two couered their bodies.", "wycliffe": "And the faces of tho and the wengis of tho weren stretchid forth aboue. Twei wyngis of eche weren ioyned togidere, and tweyne hiliden the bodies of tho.", "rotherham": "and their wings were spread above,— two of each joined one another, and two covered their bodies;", "darby": "And their faces and their wings were parted above; two [wings] of every one were joined one to another, and two covered their bodies.", "twenty": "", "jps": "Thus were their faces; and their wings were stretched upward; two wings of every one were joined one to another, and two covered their bodies.", "acv": "And their faces and their wings were separate above, two wings of each one were joined one to another, and two covered their bodies.", "anderson": "", "haweis": "", "noyes": "Thus were their faces. And their wings were expanded upward; two wings of every one were joined, and two covered their bodies.", "webster": "Thus [were] their faces: and their wings [were] stretched upward; two [wings] of every one [were] joined one to another, and two covered their bodies.", "vulgate": "et facies eorum et pinnae eorum extentae desuper duae pinnae singulorum iungebantur et duae tegebant corpora eorum;", "brenton": "And the four had their wings spread out above; each one had two joined to one another, and two covered their bodies."}}, {"v": 12, "ref": "1:12", "o": "וְ/אִ֛ישׁ אֶל עֵ֥בֶר פָּנָ֖י/ו יֵלֵ֑כוּ אֶ֣ל אֲשֶׁר֩ יִֽהְיֶה שָׁ֨מָּ/ה הָ/ר֤וּחַ לָ/לֶ֨כֶת֙ יֵלֵ֔כוּ לֹ֥א יִסַּ֖בּוּ בְּ/לֶכְתָּֽ/ן", "en": {"kjv": "And they went every one straight forward: whither the spirit was to go, they went; and they turned not when they went.", "web": "Each one went straight forward: where the spirit was to go, they went; they didn’t turn when they went.", "bsb": "Each creature went straight ahead. Wherever the spirit would go, they would go, without turning as they moved.", "asv": "And they went every one straight forward: whither the spirit was to go, they went; they turned not when they went.", "ylt": "And each straight forward they go, whither the spirit is to go, they go, they turn not round in their going.", "dra": "And every one of them went straight forward: whither the impulse of the spirit was to go, thither they went: and they turned not when they went.", "bbe": "Every one of them went straight forward; wherever the spirit was to go they went; they went on without turning.", "geneva": "And euery one went streight forward: they went whither their spirit led them, and they returned not when they went forth.", "wycliffe": "And ech of tho yede bifore his face. Where the fersnesse of the wynd was, thidur tho yeden, and turneden not ayen, whanne tho yeden.", "rotherham": "and each one straight before him, did they go,—whithersoever the spirit was minded to go, they went, they turned not when they went.", "darby": "And they went every one straight forward: whither the Spirit was to go, they went; they turned not when they went.", "twenty": "", "jps": "And they went every one straight forward; whither the spirit was to go, they went; they turned not when they went.", "acv": "And they went each one straight forward. Where the spirit was to go, they went. They did not turn when they went.", "anderson": "", "haweis": "", "noyes": "And they went every one straight forward; whither the spirit was to go, they went, and they turned not about when they went.", "webster": "And they went every one straight forward: whither the spirit was to go, they went; [and] they turned not when they went.", "vulgate": "et unumquodque coram facie sua ambulabat ubi erat impetus spiritus illuc gradiebantur nec revertebantur cum ambularent;", "brenton": "And each one went straight forward: wherever the spirit was going they went, and turned not back."}}, {"v": 13, "ref": "1:13", "o": "וּ/דְמ֨וּת הַ/חַיּ֜וֹת מַרְאֵי/הֶ֣ם כְּ/גַחֲלֵי אֵ֗שׁ בֹּֽעֲרוֹת֙ כְּ/מַרְאֵ֣ה הַ/לַּפִּדִ֔ים הִ֕יא מִתְהַלֶּ֖כֶת בֵּ֣ין הַ/חַיּ֑וֹת וְ/נֹ֣גַהּ לָ/אֵ֔שׁ וּ/מִן הָ/אֵ֖שׁ יוֹצֵ֥א בָרָֽק", "en": {"kjv": "As for the likeness of the living creatures, their appearance was like burning coals of fire, and like the appearance of lamps: it went up and down among the living creatures; and the fire was bright, and out of the fire went forth lightning.", "web": "As for the likeness of the living creatures, their appearance was like burning coals of fire, like the appearance of torches: the fire went up and down among the living creatures; and the fire was bright, and lightning went out of the fire.", "bsb": "In the midst of the living creatures was the appearance of glowing coals of fire, or of torches. Fire moved back and forth between the living creatures; it was bright, and lightning flashed out of it.", "asv": "As for the likeness of the living creatures, their appearance was like burning coals of fire, like the appearance of torches: the fire went up and down among the living creatures; and the fire was bright, and out of the fire went forth lightning.", "ylt": "As to the likeness of the living creatures, their appearances are as coals of fire--burning as the appearance of lamps; it is going up and down between the living creatures, and brightness is to the fire, and out of the fire is going forth lightning.", "dra": "And as for the likeness of the living creatures, their appearance was like that of burning coals of fire, and like the appearance of lamps. This was the vision running to and fro in the midst of the living creatures, a bright fire, and lightning going forth from the fire.", "bbe": "And between the living beings it was like burning coals of fire, as if flames were going one after the other between the living beings; and the fire was bright, and out of the fire went thunder-flames.", "geneva": "The similitude also of the beasts, and their appearance was like burning coles of fire, and like the appearance of lampes: for the fire ran among the beastes, and the fire gaue a glister, and out of the fire there went lightning.", "wycliffe": "And the licnesse of the beestis, and the biholdyng of tho, was as of brennynge coolis of fier, and as the biholdyng of laumpis. This was the siyt rennynge aboute in the myddis of beestis, the schynyng of fier, and leit goynge out of the fier.", "rotherham": "As for the likeness of the living ones, their appearance was like live coals of fire burning up like the appearance of torches, the same went to and fro between the living ones,—and the fire had brightness and out of the fire, went forth a lightning.", "darby": "And as for the likeness of the living creatures, their appearance was like burning coals of fire, as the appearance of torches: it went up and down among the living creatures; and the fire was bright; and out of the fire went forth lightning.", "twenty": "", "jps": "As for the likeness of the living creatures, their appearance was like coals of fire, burning like the appearance of torches; it flashed up and down among the living creatures; and there was brightness to the fire, and out of the fire went forth lightning.", "acv": "As for the likeness of the living creatures, their appearance was like burning coals of fire, like the appearance of torches. It went up and down among the living creatures, and the fire was bright, and out of the fire went forth lightning.", "anderson": "", "haweis": "", "noyes": "And the appearance of the living creatures was as coals of fire, burning like torches; and the fire moved about among the living creatures, and shone forth brightly; and out of the fire came forth lightning.", "webster": "As for the likeness of the living creatures, their appearance [was] like burning coals of fire, [and] like the appearance of lamps: it went up and down among the living creatures; and the fire was bright, and out of the fire went forth lightning.", "vulgate": "et similitudo animalium aspectus eorum quasi carbonum ignis ardentium et quasi aspectus lampadarum haec erat visio discurrens in medio animalium splendor ignis et de igne fulgor egrediens;", "brenton": "And in the midst of the living creatures there was an appearance as of burning coals of fire, as an appearance of lamps turning among the living creatures; and the brightness of fire, and out of the fire came forth lightning."}}, {"v": 14, "ref": "1:14", "o": "וְ/הַ/חַיּ֖וֹת רָצ֣וֹא וָ/שׁ֑וֹב כְּ/מַרְאֵ֖ה הַ/בָּזָֽק", "en": {"kjv": "And the living creatures ran and returned as the appearance of a flash of lightning.", "web": "The living creatures ran and returned as the appearance of a flash of lightning.", "bsb": "The creatures were darting back and forth as quickly as flashes of lightning.", "asv": "And the living creatures ran and returned as the appearance of a flash of lightning.", "ylt": "And the living creatures are running, and turning back, as the appearance of the flash.", "dra": "And the living creatures ran and returned like flashes of lightning.", "bbe": "And the living beings went out and came back as quickly as a thunder-flame.", "geneva": "And the beastes ranne, and returned like vnto lightning.", "wycliffe": "And the beestis yeden, and turneden ayen at the licnesse of leit schynynge.", "rotherham": "And the living ones ran and returned,—like the appearance of a flash of lightning.", "darby": "And the living creatures ran and returned as the appearance of a flash of lightning.", "twenty": "", "jps": "And the living creatures ran and returned as the appearance of a flash of lightning.", "acv": "And the living creatures ran and returned as the appearance of a flash of lightning.", "anderson": "", "haweis": "", "noyes": "And the living creatures ran backward and forward like a flash of lightning.", "webster": "And the living creatures ran and returned as the appearance of a flash of lightning.", "vulgate": "et animalia ibant et revertebantur in similitudinem fulguris coruscantis;", "brenton": ""}}, {"v": 15, "ref": "1:15", "o": "וָ/אֵ֖רֶא הַ/חַיּ֑וֹת וְ/הִנֵּה֩ אוֹפַ֨ן אֶחָ֥ד בָּ/אָ֛רֶץ אֵ֥צֶל הַ/חַיּ֖וֹת לְ/אַרְבַּ֥עַת פָּנָֽי/ו", "en": {"kjv": "Now as I beheld the living creatures, behold one wheel upon the earth by the living creatures, with his four faces.", "web": "Now as I saw the living creatures, behold, one wheel on the earth beside the living creatures, for each of the four faces of it.", "bsb": "When I looked at the living creatures, I saw a wheel on the ground beside each creature with its four faces.", "asv": "Now as I beheld the living creatures, behold, one wheel upon the earth beside the living creatures, for each of the four faces thereof.", "ylt": "And I see the living creatures, and lo, one wheel is in the earth, near the living creatures, at its four faces.", "dra": "Now as I beheld the living creatures, there appeared upon the earth by the living creatures one wheel with four faces.", "bbe": "Now while I was looking at the four living beings, I saw one wheel on the earth, by the side of the living beings, for the four of them.", "geneva": "Nowe as I behelde the beastes, beholde, a wheele appeared vpon the earth by the beastes, hauing foure faces.", "wycliffe": "And whanne Y bihelde the beestis, o wheel, hauuynge foure faces, apperide on the erthe, bisidis the beestis.", "rotherham": "And I looked at the living ones,—and lo! one wheel upon the earth beside the living ones for each of his four faces,", "darby": "And I looked at the living creatures, and behold, one wheel upon the earth beside the living creatures, toward their four faces.", "twenty": "", "jps": "Now as I beheld the living creatures, behold one wheel at the bottom hard by the living creatures, at the four faces thereof.", "acv": "Now as I beheld the living creatures, behold, one wheel was upon the earth beside the living creatures, for each of the four faces of it.", "anderson": "", "haweis": "", "noyes": "Now as I beheld the living creatures, behold, there stood a wheel upon the earth by each of the living creatures, with its four sides.", "webster": "Now as I beheld the living creatures, behold one wheel upon the earth by the living creatures, with his four faces.", "vulgate": "cumque aspicerem animalia apparuit rota una super terram iuxta animalia habens quattuor facies;", "brenton": "And I looked, and, behold, the four had each one wheel on the ground near the living creatures."}}, {"v": 16, "ref": "1:16", "o": "מַרְאֵ֨ה הָ/אוֹפַנִּ֤ים וּ/מַעֲשֵׂי/הֶם֙ כְּ/עֵ֣ין תַּרְשִׁ֔ישׁ וּ/דְמ֥וּת אֶחָ֖ד לְ/אַרְבַּעְתָּ֑/ן וּ/מַרְאֵי/הֶם֙ וּ/מַ֣עֲשֵׂי/הֶ֔ם כַּ/אֲשֶׁ֛ר יִהְיֶ֥ה הָ/אוֹפַ֖ן בְּ/ת֥וֹךְ הָ/אוֹפָֽן", "en": {"kjv": "The appearance of the wheels and their work was like unto the colour of a beryl: and they four had one likeness: and their appearance and their work was as it were a wheel in the middle of a wheel.", "web": "The appearance of the wheels and their work was like a beryl: and the four of them had one likeness; and their appearance and their work was as it were a wheel within a wheel.", "bsb": "The workmanship of the wheels looked like the gleam of beryl, and all four had the same likeness. Their workmanship looked like a wheel within a wheel.", "asv": "The appearance of the wheels and their work was like unto a beryl: and they four had one likeness; and their appearance and their work was as it were a wheel within a wheel.", "ylt": "The appearance of the wheels and their works is as the colour of beryl, and one likeness is to them four, and their appearances and their works are as it were the wheel in the midst of the wheel.", "dra": "And the appearance of the wheels, and the work of them was like the appearance of the sea: and the four had all one likeness: and their appearance and their work was as it were a wheel in the midst of a wheel.", "bbe": "The form of the wheels and their work was like a beryl; the four of them had the same form and design, and they were like a wheel inside a wheel.", "geneva": "The facion of the wheeles and their worke was like vnto a chrysolite: and they foure had one forme, and their facion, and their worke was as one wheele in another wheele.", "wycliffe": "And the biholdyng of the wheelis and the werk of tho was as the siyt of the see; and o licnesse was of tho foure; and the biholdyng and the werkis of tho, as if a wheel be in the myddis of a wheel.", "rotherham": "The appearance of the wheels and of their structure was like a Tarshish-stone to look upon, and they four had one likeness,—and their appearance and their structure were just as would be a wheel in the midst of a wheel.", "darby": "The appearance of the wheels and their work was as the look of a chrysolite; and they four had one likeness; and their appearance and their work was as it were a wheel in the middle of a wheel.", "twenty": "", "jps": "The appearance of the wheels and their work was like unto the colour of a beryl; and they four had one likeness; and their appearance and their work was as it were a wheel within a wheel.", "acv": "The appearance of the wheels and their work was like a beryl. And those four had one likeness, and their appearance and their work was as it were a wheel within a wheel.", "anderson": "", "haweis": "", "noyes": "The appearance of the wheels, and their work, was like that of a chrysolite, and all four had one form, and their appearance and their work was as if a wheel had been within a wheel.", "webster": "The appearance of the wheels and their work [was] like the color of a beryl: and they four had one likeness: and their appearance and their work [was] as it were a wheel in the middle of a wheel.", "vulgate": "et aspectus rotarum et opus earum quasi visio maris et una similitudo ipsarum quattuor et aspectus earum et opera quasi sit rota in medio rotae;", "brenton": "And the appearance of the wheels was as the appearance of beryl: and the four had one likeness: and their work was as it were a wheel in a wheel."}}, {"v": 17, "ref": "1:17", "o": "עַל אַרְבַּ֥עַת רִבְעֵי/הֶ֖ן בְּ/לֶכְתָּ֣/ם יֵלֵ֑כוּ לֹ֥א יִסַּ֖בּוּ בְּ/לֶכְתָּֽ/ן", "en": {"kjv": "When they went, they went upon their four sides: and they turned not when they went.", "web": "When they went, they went in their four directions: they didn’t turn when they went.", "bsb": "As they moved, they went in any of the four directions, without pivoting as they moved.", "asv": "When they went, they went in their four directions: they turned not when they went.", "ylt": "On their four sides, in their going they go, they turn not round in their going.", "dra": "When they went, they went by their four parts: and they turned not when they went.", "bbe": "The four of them went straight forward without turning to one side.", "geneva": "Whe they went, they went vpon their foure sides, and they returned not when they went.", "wycliffe": "Tho goynge yeden bi foure partis of tho, and turneden not ayen, whanne tho yeden.", "rotherham": "Upon their four sides, when they went, so did they go,—they turned not when they went.", "darby": "When they went, they went upon their four sides; they turned not when they went.", "twenty": "", "jps": "When they went, they went toward their four sides; they turned not when they went.", "acv": "When they went, they went in their four directions. They did not turn when they went.", "anderson": "", "haweis": "", "noyes": "When they went, they went upon their four sides, and they turned not about when they went.", "webster": "When they went, they went upon their four sides: [and] they returned not when they went.", "vulgate": "per quattuor partes earum euntes ibant et non revertebantur cum ambularent;", "brenton": "They went on their four sides: they turned not as they went;"}}, {"v": 18, "ref": "1:18", "o": "וְ/גַ֨בֵּי/הֶ֔ן וְ/גֹ֥בַהּ לָ/הֶ֖ם וְ/יִרְאָ֣ה לָ/הֶ֑ם וְ/גַבֹּתָ֗/ם מְלֵאֹ֥ת עֵינַ֛יִם סָבִ֖יב לְ/אַרְבַּעְתָּֽ/ן", "en": {"kjv": "As for their rings, they were so high that they were dreadful; and their rings were full of eyes round about them four.", "web": "As for their rims, they were high and dreadful; and the four of them had their rims full of eyes all around.", "bsb": "Their rims were high and awesome, and all four rims were full of eyes all around.", "asv": "As for their rims, they were high and dreadful; and they four had their rims full of eyes round about.", "ylt": "As to their rings, they are both high and fearful, and their rings are full of eyes round about them four.", "dra": "The wheels had also a size, and a height, and a dreadful appearance: and the whole body was full of eyes round about all the four.", "bbe": "And I saw that they had edges, and their edges, even of the four, were full of eyes round about.", "geneva": "They had also rings, and height, and were fearefull to beholde, and their rings were full of eyes, round about them foure.", "wycliffe": "Also stature, and hiynesse, and orible biholdyng was to the wheelis; and al the bodi was ful of iyen in the cumpas of tho foure.", "rotherham": "As for their rings, they were so high that they were terrible, -and their rings full of eyes round about, had they four.", "darby": "As for their rims, they were high and dreadful; and they four had their rims full of eyes round about.", "twenty": "", "jps": "As for their rings, they were high and they were dreadful; and they four had their rings full of eyes round about.", "acv": "As for their rims, they were high and fearful. And those four had their rims full of eyes round about.", "anderson": "", "haweis": "", "noyes": "As for their felloes, they were high and terrible; and their felloes were full of eyes round about upon all four of them.", "webster": "As for their rings, they were so high that they were dreadful; and their rings [were] full of eyes around them four.", "vulgate": "statura quoque erat rotis et altitudo et horribilis aspectus et totum corpus plenum oculis in circuitu ipsarum quattuor;", "brenton": "neither did their backs turn: and they were high: and I beheld them, and the backs of them four were full of eyes round about."}}, {"v": 19, "ref": "1:19", "o": "וּ/בְ/לֶ֨כֶת֙ הַֽ/חַיּ֔וֹת יֵלְכ֥וּ הָ/אוֹפַנִּ֖ים אֶצְלָ֑/ם וּ/בְ/הִנָּשֵׂ֤א הַֽ/חַיּוֹת֙ מֵ/עַ֣ל הָ/אָ֔רֶץ יִנָּשְׂא֖וּ הָ/אוֹפַנִּֽים", "en": {"kjv": "And when the living creatures went, the wheels went by them: and when the living creatures were lifted up from the earth, the wheels were lifted up.", "web": "When the living creatures went, the wheels went beside them; and when the living creatures were lifted up from the earth, the wheels were lifted up.", "bsb": "So as the living creatures moved, the wheels moved beside them, and when the creatures rose from the ground, the wheels also rose.", "asv": "And when the living creatures went, the wheels went beside them; and when the living creatures were lifted up from the earth, the wheels were lifted up.", "ylt": "And in the going of the living creatures, the wheels go beside them, and in the living creatures being lifted up from off the earth, lifted up are the wheels.", "dra": "And, when the living creatures went, the wheels also went together by them: and when the living creatures were lifted up from the earth, the wheels also were lifted up with them.", "bbe": "And when the living beings went on, the wheels went by their side; and when the living beings were lifted up from the earth, the wheels were lifted up.", "geneva": "And when the beastes went, the wheeles went with them: and when the beasts were lift vp from the earth, the wheeles were lift vp.", "wycliffe": "And whanne the beestis yeden, the wheelis also yeden togidere bisidis tho. And whanne the beestis weren reisid fro the erthe, the wheelis also weren reisid togidere.", "rotherham": "And when the living ones went, the wheels went beside them,—and when the living ones were lifted up from the earth, the wheels were lifted up:", "darby": "And when the living creatures went, the wheels went beside them; and when the living creatures were lifted up from the earth, the wheels were lifted up.", "twenty": "", "jps": "And when the living creatures went, the wheels went hard by them; and when the living creatures were lifted up from the bottom, the wheels were lifted up.", "acv": "And when the living creatures went, the wheels went beside them. And when the living creatures were lifted up from the earth, the wheels were lifted up.", "anderson": "", "haweis": "", "noyes": "And when the living creatures went, the wheels went beside them; and when the living creatures were lifted up from the earth, the wheels were lifted up.", "webster": "And when the living creatures went, the wheels went by them: and when the living creatures were lifted up from the earth, the wheels were lifted up.", "vulgate": "cumque ambularent animalia ambulabant pariter et rotae iuxta ea et cum elevarentur animalia de terra elevabantur simul et rotae;", "brenton": "And when the living creatures went, the wheels went by them: and when the living creatures lifted themselves off the earth, the wheels were lifted off."}}, {"v": 20, "ref": "1:20", "o": "עַ֣ל אֲשֶׁר֩ יִֽהְיֶה שָּׁ֨ם הָ/ר֤וּחַ לָ/לֶ֨כֶת֙ יֵלֵ֔כוּ שָׁ֥מָּ/ה הָ/ר֖וּחַ לָ/לֶ֑כֶת וְ/הָ/אוֹפַנִּ֗ים יִנָּשְׂאוּ֙ לְ/עֻמָּתָ֔/ם כִּ֛י ר֥וּחַ הַ/חַיָּ֖ה בָּ/אוֹפַנִּֽים", "en": {"kjv": "Whithersoever the spirit was to go, they went, thither was their spirit to go; and the wheels were lifted up over against them: for the spirit of the living creature was in the wheels.", "web": "Wherever the spirit was to go, they went; there was the spirit to go: and the wheels were lifted up beside them; for the spirit of the living creature was in the wheels.", "bsb": "Wherever the spirit would go, they would go, and the wheels would rise alongside them, because the spirit of the living creatures was in the wheels.", "asv": "Whithersoever the spirit was to go, they went; thither was the spirit to go: and the wheels were lifted up beside them; for the spirit of the living creature was in the wheels.", "ylt": "Whither the spirit is to go, they go, thither the spirit is to go, and the wheels are lifted up over-against them, for a living spirit is in the wheels.", "dra": "Withersoever the spirit went, thither as the spirit went the wheels also were lifted up withal, and followed it: for the spirit of life was in the wheels.", "bbe": "Wherever the spirit was to go they went; and the wheels were lifted up by their side: for the spirit of the living beings was in the wheels.", "geneva": "Whither the spirit led them, they went, and thither did the spirite of the wheeles leade them, and the wheeles were lifted vp besides them: for the spirit of the beastes was in the wheeles.", "wycliffe": "Whidur euere the spirit yede, whanne the spirit yede thedur, also the wheelis suynge it weren reisid togidere; for whi the spirit of lijf was in the wheelis.", "rotherham": "whithersoever the spirit was minded to go, they went—thither was the spirit minded to go,—and the wheels would be lifted up along with them, for the spirit of the living one was in the wheels:", "darby": "Whithersoever the Spirit was to go, they went, thither would [their] spirit go; and the wheels were lifted up along with them: for the spirit of the living creature was in the wheels.", "twenty": "", "jps": "Whithersoever the spirit was to go, as the spirit was to go thither, so they went; and the wheels were lifted up beside them; for the spirit of the living creature was in the wheels.", "acv": "Wherever the spirit was to go, they went; there the spirit was to go. And the wheels were lifted up beside them, for the spirit of the living creature was in the wheels.", "anderson": "", "haweis": "", "noyes": "Whithersoever the spirit was to go, they went, whithersoever the spirit was to go; and the wheels were lifted up beside them; for the spirit of the living creatures was in the wheels.", "webster": "Whithersoever the spirit was to go, they went, thither [was their] spirit to go; and the wheels were lifted up over against them: for the spirit of the living creature [was] in the wheels.", "vulgate": "quocumque ibat spiritus illuc eunte spiritu et rotae pariter levabantur sequentes eum spiritus enim vitae erat in rotis;", "brenton": "Wherever the cloud happened to be, there was the spirit ready to go: the wheels went and were lifted up with them; because the spirit of life was in the wheels."}}, {"v": 21, "ref": "1:21", "o": "בְּ/לֶכְתָּ֣/ם יֵלֵ֔כוּ וּ/בְ/עָמְדָ֖/ם יַֽעֲמֹ֑דוּ וּֽ/בְ/הִנָּשְׂאָ֞/ם מֵ/עַ֣ל הָ/אָ֗רֶץ יִנָּשְׂא֤וּ הָ/אֽוֹפַנִּים֙ לְ/עֻמָּתָ֔/ם כִּ֛י ר֥וּחַ הַ/חַיָּ֖ה בָּ/אוֹפַנִּֽים", "en": {"kjv": "When those went, these went; and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up over against them: for the spirit of the living creature was in the wheels.", "web": "When those went, these went; and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up beside them: for the spirit of the living creature was in the wheels.", "bsb": "When the creatures moved, the wheels moved; when the creatures stood still, the wheels stood still; and when the creatures rose from the ground, the wheels rose alongside them, because the spirit of the living creatures was in the wheels.", "asv": "When those went, these went; and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up beside them: for the spirit of the living creature was in the wheels.", "ylt": "In their going, they go; and in their standing, they stand; and in their being lifted up from off the earth, lifted up are the wheels over-against them; for a living spirit is in the wheels.", "dra": "When those went these went, and when those stood these stood, and when those were lifted up from the earth, the wheels were lifted up together, and followed them: for the spirit of life was in the wheels.", "bbe": "When these went on, the others went; and when these came to rest, the others came to rest; and when these were lifted up from the earth, the wheels were lifted up by their side: for the spirit of the living beings was in the wheels.", "geneva": "When the beastes went, they went, and when they stoode, they stoode, and when they were lifted vp from the earth, the wheeles were lifted vp besides them: for the spirite of the beastes was in the wheeles.", "wycliffe": "Tho yeden with the beestis goynge, and tho stoden with the beestis stondynge. And with the beestis reisid fro erthe, also the wheelis suynge tho beestis weren reisid togidere; for the spirit of lijf was in the wheelis.", "rotherham": "when they went, these went, and when they stood, these stood,—and when they were lifted up from off the earth, the wheels were lifted up along with them, for the spirit of the living one was in the wheels.", "darby": "When those went, they went; and when those stood, they stood; and when those were lifted up from the earth, the wheels were lifted up along with them: for the spirit of the living creature was in the wheels.", "twenty": "", "jps": "When those went, these went, and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up beside them; for the spirit of the living creature was in the wheels.", "acv": "When those went, these went, and when those stood, these stood, and when those were lifted up from the earth, the wheels were lifted up beside them, for the spirit of the living creature was in the wheels.", "anderson": "", "haweis": "", "noyes": "When those went, these went; and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up beside them; for the spirit of the living creatures was in the wheels.", "webster": "When those went, [these] went; and when those stood, [these] stood; and when those were lifted up from the earth, the wheels were lifted up over against them: for the spirit of the living creature [was] in the wheels.", "vulgate": "cum euntibus ibant et cum stantibus stabant et cum elevatis a terra pariter elevabantur et rotae sequentes ea quia spiritus vitae erat in rotis;", "brenton": "When those went, the wheels went; and when those stood, the wheels stood; and when those lifted themselves off the earth, they were lifted off with them: for the spirit of life was in the wheels."}}, {"v": 22, "ref": "1:22", "o": "וּ/דְמ֞וּת עַל רָאשֵׁ֤י הַ/חַיָּה֙ רָקִ֔יעַ כְּ/עֵ֖ין הַ/קֶּ֣רַח הַ/נּוֹרָ֑א נָט֥וּי עַל רָאשֵׁי/הֶ֖ם מִ/לְ/מָֽעְלָ/ה", "en": {"kjv": "And the likeness of the firmament upon the heads of the living creature was as the colour of the terrible crystal, stretched forth over their heads above.", "web": "Over the head of the living creature there was the likeness of an expanse, like the awesome crystal to look on, stretched out over their heads above.", "bsb": "Spread out above the heads of the living creatures was the likeness of an awesome expanse, gleaming like crystal.", "asv": "And over the head of the living creature there was the likeness of a firmament, like the terrible crystal to look upon, stretched forth over their heads above.", "ylt": "And a likeness is over the heads of the living creatures of an expanse, as the colour of the fearful ice, stretched out over their heads from above.", "dra": "And over the heads of the living creatures was the likeness of the firmament, the appearance of crystal terrible to behold, and stretched out over their heads above.", "bbe": "And over the heads of the living beings there was the form of an arch, looking like ice, stretched out over their heads on high.", "geneva": "And the similitude of the firmament vpon the heads of the beasts was wonderfull, like vnto chrystall, spred ouer their heads aboue.", "wycliffe": "And the licnesse of the firmament was aboue the heed of the beestis, and as the biholdyng of orible cristal, and stretchid abrood on the heed of tho beestis aboue.", "rotherham": "And there was a likeness over the heads of the living one—an expanse, like terrible crystal to look upon, -stretched forth over their heads above.", "darby": "And there was the likeness of an expanse over the heads of the living creature, as the look of the terrible crystal, stretched forth over their heads above.", "twenty": "", "jps": "And over the heads of the living creatures there was the likeness of a firmament, like the colour of the terrible ice, stretched forth over their heads above.", "acv": "And over the head of the living creature there was the likeness of a firmament, like awesome crystal to look upon, stretched forth over their heads above.", "anderson": "", "haweis": "", "noyes": "And over the heads of the living creatures was the appearance of a firmament, like crystal, terrible, spread out over their heads above.", "webster": "And the likeness of the firmament upon the heads of the living creature [was] as the color of the terrible crystal, stretched forth over their heads above.", "vulgate": "et similitudo super caput animalium firmamenti quasi aspectus cristalli horribilis et extenti super capita eorum desuper;", "brenton": "And the likeness over the heads of the living creatures was as a firmament, as the appearance of crystal, spread out over their wings above."}}, {"v": 23, "ref": "1:23", "o": "וְ/תַ֨חַת֙ הָ/רָקִ֔יעַ כַּנְפֵי/הֶ֣ם יְשָׁר֔וֹת אִשָּׁ֖ה אֶל אֲחוֹתָ֑/הּ לְ/אִ֗ישׁ שְׁתַּ֤יִם מְכַסּוֹת֙ לָ/הֵ֔נָּה וּ/לְ/אִ֗ישׁ שְׁתַּ֤יִם מְכַסּוֹת֙ לָ/הֵ֔נָּה אֵ֖ת גְּוִיֹּתֵי/הֶֽם", "en": {"kjv": "And under the firmament were their wings straight, the one toward the other: every one had two, which covered on this side, and every one had two, which covered on that side, their bodies.", "web": "Under the expanse were their wings straight, the one toward the other: each one had two which covered on this side, and every one had two which covered on that side, their bodies.", "bsb": "And under the expanse, their wings stretched out toward one another. Each one also had two wings covering its body.", "asv": "And under the firmament were their wings straight, the one toward the other: every one had two which covered on this side, and every one had two which covered on that side, their bodies.", "ylt": "And under the expanse their wings are straight, one toward the other, to each are two covering on this side, and to each are two covering on that side--their bodies.", "dra": "And under the firmament were their wings straight, the one toward the other, every one with two wings covered his body, and the other was covered in like manner.", "bbe": "Under the arch their wings were straight, one stretched out to another: every one had two wings covering their bodies on this side and two covering their bodies on that side.", "geneva": "And vnder the firmament were their wings streight, the one toward the other: every one had two, which couered the, and euery one had two, which couered their bodies.", "wycliffe": "Forsothe vndur the firmament the wyngis of tho beestis weren streiyt, of oon to anothir; ech beeste hilide his bodi with twei wyngis, and an other was hilid in lijk maner.", "rotherham": "And under the expanse, their wings were straight, one towards another,—each one had two covering on this side, and each one had two covering on that side, their bodies.", "darby": "And under the expanse were their wings straight, the one toward the other: every one had two which covered on this side, and every one had two which covered on that side their bodies.", "twenty": "", "jps": "And under the firmament were their wings conformable the one to the other; this one of them had two which covered, and that one of them had two which covered, their bodies.", "acv": "And under the firmament their wings were straight, the one toward the other. Each one had two which covered their bodies on this side, and each one had two which covered on that side.", "anderson": "", "haweis": "", "noyes": "And under the firmament were their wings upright, the one toward the other; and every one had two, which covered his body.", "webster": "And under the firmament [were] their wings straight, the one towards the other: every one had two, which covered on this side, and every one had two, which covered on that side, their bodies.", "vulgate": "sub firmamento autem pinnae eorum rectae alterius ad alterum unumquodque duabus alis velabat corpus suum et alterum similiter velabatur;", "brenton": "And their wings were spread out under the firmament, reaching one to the other; two wings to each, covering their bodies."}}, {"v": 24, "ref": "1:24", "o": "וָ/אֶשְׁמַ֣ע אֶת ק֣וֹל כַּנְפֵי/הֶ֡ם כְּ/קוֹל֩ מַ֨יִם רַבִּ֤ים כְּ/קוֹל שַׁדַּי֙ בְּ/לֶכְתָּ֔/ם ק֥וֹל הֲמֻלָּ֖ה כְּ/ק֣וֹל מַחֲנֶ֑ה בְּ/עָמְדָ֖/ם תְּרַפֶּ֥ינָה כַנְפֵי/הֶֽן", "en": {"kjv": "And when they went, I heard the noise of their wings, like the noise of great waters, as the voice of the Almighty, the voice of speech, as the noise of an host: when they stood, they let down their wings.", "web": "When they went, I heard the noise of their wings like the noise of great waters, like the voice of the Almighty, a noise of tumult like the noise of an army: when they stood, they let down their wings.", "bsb": "When the creatures moved, I heard the sound of their wings like the roar of many waters, like the voice of the Almighty, like the tumult of an army. When they stood still, they lowered their wings.", "asv": "And when they went, I heard the noise of their wings like the noise of great waters, like the voice of the Almighty, a noise of tumult like the noise of a host: when they stood, they let down their wings.", "ylt": "And I hear the noise of their wings, as the noise of many waters, as the noise of the Mighty One, in their going--the noise of tumult, as the noise of a camp, in their standing they let fall their wings.", "dra": "And I heard the noise of their wings, like the noise of many waters, as it were the voice of the most high God: when they walked, it was like the voice of a multitude, like the noise of an army, and when they stood, their wings were let down.", "bbe": "And when they went, the sound of their wings was like the sound of great waters to my ears, like the voice of the Ruler of all, a sound like the rushing of an army: when they came to rest they let down their wings.", "geneva": "And when they went foorth, I heard the noyse of their wings, like the noyse of great waters, and as the voyce of the Almightie, euen the voyce of speach, as the noyse of an host: and when they stood, they let downe their wings.", "wycliffe": "And Y herde the sown of wyngis, as the sown of many watris, as the sown of hiy God. Whanne tho yeden, ther was as a sown of multitude, as the sown of oostis of batel; and whanne tho stoden, the wyngis of tho weren late doun.", "rotherham": "And I heard the sound of their wings, as the sound of many waters, as the sound of the Almighty, when they went, the sound of a storm as the sound of a host,—when they stood, they let down their wings,", "darby": "And when they went, I heard the noise of their wings, like the noise of great waters, as the voice of the Almighty, a tumultuous noise, as the noise of a host: when they stood, they let down their wings;", "twenty": "", "jps": "And when they went, I heard the noise of their wings like the noise of great waters, like the voice of the Almighty, a noise of tumult like the noise of a host; when they stood, they let down their wings.", "acv": "And when they went, I heard the noise of their wings like the noise of great waters, like the voice of the Almighty, a noise of tumult like the noise of a host. When they stood, they let down their wings.", "anderson": "", "haweis": "", "noyes": "And I heard the sound of their wings, as the sound of great waters, as the voice of the Almighty, when they went,—a sound like the noise of a host. And when they stood still, they let down their wings.", "webster": "And when they went, I heard the noise of their wings, like the noise of great waters, as the voice of the Almighty, the voice of speech, as the noise of a host: when they stood, they let down their wings.", "vulgate": "et audiebam sonum alarum quasi sonum aquarum multarum quasi sonum sublimis Dei cum ambularent quasi sonus erat multitudinis ut sonus castrorum cumque starent dimittebantur pinnae eorum;", "brenton": "And I heard the sound of their wings when they went, as the sound of much water: and when they stood, their wings were let down."}}, {"v": 25, "ref": "1:25", "o": "וַ/יְהִי ק֕וֹל מֵ/עַ֕ל לָ/רָקִ֖יעַ אֲשֶׁ֣ר עַל רֹאשָׁ֑/ם בְּ/עָמְדָ֖/ם תְּרַפֶּ֥ינָה כַנְפֵי/הֶֽן", "en": {"kjv": "And there was a voice from the firmament that was over their heads, when they stood, and had let down their wings.", "web": "There was a voice above the expanse that was over their heads: when they stood, they let down their wings.", "bsb": "And there came a voice from above the expanse over their heads as they stood still with their wings lowered.", "asv": "And there was a voice above the firmament that was over their heads: when they stood, they let down their wings.", "ylt": "And there is a voice from above the expanse, that is above their head: in their standing they let fall their wings.", "dra": "For when a voice came from above the firmament, that was over their heads, they stood, and let down their wings.", "bbe": "And there was a voice from the top of the arch which was over their heads: when they came to rest they let down their wings.", "geneva": "And there was a voyce from the firmament, that was ouer their heads, when they stoode, and had let downe their wings.", "wycliffe": "For whi whanne a vois was maad on the firmament, that was on the heed of tho, tho stoden, and leten doun her wyngis.", "rotherham": "And there was a voice above the expanse that was over their head,—when they stood, they let down their wings.", "darby": "and there was a voice from above the expanse that was over their heads. When they stood, they let down their wings.", "twenty": "", "jps": "For, when there was a voice above the firmament that was over their heads, as they stood, they let down their wings.", "acv": "And there was a voice above the firmament that was over their heads. When they stood, they let down their wings.", "anderson": "", "haweis": "", "noyes": "And there was a voice from the firmament, that was over their heads; and they stood still, and let down their wings.", "webster": "And there was a voice from the firmament that [was] over their heads, when they stood, [and] had let down their wings.", "vulgate": "nam cum fieret vox supra firmamentum quod erat super caput eorum stabant et submittebant alas suas;", "brenton": "And lo! a voice from above the firmament"}}, {"v": 26, "ref": "1:26", "o": "וּ/מִ/מַּ֗עַל לָ/רָקִ֨יעַ֙ אֲשֶׁ֣ר עַל רֹאשָׁ֔/ם כְּ/מַרְאֵ֥ה אֶֽבֶן סַפִּ֖יר דְּמ֣וּת כִּסֵּ֑א וְ/עַל֙ דְּמ֣וּת הַ/כִּסֵּ֔א דְּמ֞וּת כְּ/מַרְאֵ֥ה אָדָ֛ם עָלָ֖י/ו מִ/לְ/מָֽעְלָ/ה", "en": {"kjv": "And above the firmament that was over their heads was the likeness of a throne, as the appearance of a sapphire stone: and upon the likeness of the throne was the likeness as the appearance of a man above upon it.", "web": "Above the expanse that was over their heads was the likeness of a throne, as the appearance of a sapphire stone; and on the likeness of the throne was a likeness as the appearance of a man on it above.", "bsb": "Above the expanse over their heads was the likeness of a throne with the appearance of sapphire, and on the throne high above was a figure like that of a man.", "asv": "And above the firmament that was over their heads was the likeness of a throne, as the appearance of a sapphire stone; and upon the likeness of the throne was a likeness as the appearance of a man upon it above.", "ylt": "And above the expanse that is over their head, as an appearance of a sapphire stone, is the likeness of a throne, and on the likeness of the throne a likeness, as the appearance of man upon it from above.", "dra": "And above the firmament that was over their heads, was the likeness of a throne, as the appearance of the sapphire stone, and upon the likeness of the throne, was the likeness of the appearance of a man above upon it.", "bbe": "And on the top of the arch which was over their heads was the form of a king's seat, like a sapphire stone; and on the form of the seat was the form of a man seated on it on high.", "geneva": "And aboue the firmament that was ouer their heads, was the facion of a throne like vnto a saphir stone, and vpon the similitude of the throne was by appearance, as the similitude of a man aboue vpon it.", "wycliffe": "And on the firmament, that was aboue the heed of tho, was as the biholdyng of a saphire stoon, the licnesse of a trone; and on the licnesse of the trone was a licnesse, as the biholdyng of a man aboue.", "rotherham": "And above the expanse that was over their heads, as the appearance of a sapphire stone, was the likeness of a throne,—and upon the likeness of a throne, was a likeness as the appearance of a man upon it above.", "darby": "And above the expanse that was over their heads was the likeness of a throne, as the appearance of a sapphire stone; and upon the likeness of the throne was a likeness as the appearance of a man above upon it.", "twenty": "", "jps": "And above the firmament that was over their heads was the likeness of a throne, as the appearance of a sapphire stone; and upon the likeness of the throne was a likeness as the appearance of a man upon it above.", "acv": "And above the firmament that was over their heads was the likeness of a throne, as the appearance of a sapphire stone. And upon the likeness of the throne was a likeness as the appearance of a man upon it above.", "anderson": "", "haweis": "", "noyes": "And above the firmament over their heads was an appearance like a sapphire-stone, the form of a throne; and upon the form of the throne there was a form like that of a man above.", "webster": "And above the firmament that [was] over their heads [was] the likeness of a throne, as the appearance of a sapphire stone: and upon the likeness of the throne [was] the likeness as the appearance of a man above upon it.", "vulgate": "et super firmamentum quod erat inminens capiti eorum quasi aspectus lapidis sapphyri similitudo throni et super similitudinem throni similitudo quasi aspectus hominis desuper;", "brenton": "that was over their head, there was as the appearance of a sapphire stone, and the likeness of a throne upon it: and upon the likeness of the throne was the likeness as an appearance of a man above."}}, {"v": 27, "ref": "1:27", "o": "וָ/אֵ֣רֶא כְּ/עֵ֣ין חַשְׁמַ֗ל כְּ/מַרְאֵה אֵ֤שׁ בֵּֽית לָ/הּ֙ סָבִ֔יב מִ/מַּרְאֵ֥ה מָתְנָ֖י/ו וּ/לְ/מָ֑עְלָ/ה וּ/מִ/מַּרְאֵ֤ה מָתְנָי/ו֙ וּ/לְ/מַ֔טָּה רָאִ֨יתִי֙ כְּ/מַרְאֵה אֵ֔שׁ וְ/נֹ֥גַֽהּ ל֖/וֹ סָבִֽיב", "en": {"kjv": "And I saw as the colour of amber, as the appearance of fire round about within it, from the appearance of his loins even upward, and from the appearance of his loins even downward, I saw as it were the appearance of fire, and it had brightness round about.", "web": "I saw as it were glowing metal, as the appearance of fire within it all around, from the appearance of his waist and upward; and from the appearance of his waist and downward I saw as it were the appearance of fire, and there was brightness around him.", "bsb": "From what seemed to be His waist up, I saw a gleam like amber, with what looked like fire within it all around. And from what seemed to be His waist down, I saw what looked like fire; and brilliant light surrounded Him.", "asv": "And I saw as it were glowing metal, as the appearance of fire within it round about, from the appearance of his loins and upward; and from the appearance of his loins and downward I saw as it were the appearance of fire, and there was brightness round about him.", "ylt": "And I see as the colour of copper, as the appearance of fire within it round about, from the appearance of his loins and upward, and from the appearance of his loins and downward, I have seen as the appearance of fire, and brightness is to it round about.", "dra": "And I saw as it were the resemblance of amber as the appearance of fire within it round about: from his loins and upward, and from his loins downward, I saw as it were the resemblance of fire shining round about.", "bbe": "And I saw it coloured like electrum, with the look of fire in it and round it, going up from what seemed to be the middle of his body; and going down from what seemed to be the middle of his body I saw what was like fire, and there was a bright light shining round him.", "geneva": "And I sawe as the appearance of amber, and as the similitude of fire round about within it to looke to, euen from his loynes vpwarde: and to looke to, euen from his loynes downewarde, I sawe as a likenesse of fire, and brightnesse round about it.", "wycliffe": "And Y siy as a licnesse of electre, as the biholding of fier with ynne, bi the cumpas therof; fro the lendis of hym and aboue, and fro the lendis of him til to bynethe, Y siy as the licnesse of fier schynynge in cumpas,", "rotherham": "And I saw as burnished copper to look upon, as the appearance of fire within it round about, from the appearance of his loins and upwards and from the appearance of his loins and downwards, saw I as the appearance of fire, and he had brightness round about:", "darby": "And I saw as the look of glowing brass, as the appearance of fire, within it round about; from the appearance of his loins and upward, and from the appearance of his loins and downward, I saw as it were the appearance of fire, and it had brightness round about.", "twenty": "", "jps": "And I saw as the colour of electrum, as the appearance of fire round about enclosing it, from the appearance of his loins and upward; and from the appearance of his loins and downward I saw as it were the appearance of fire, and there was brightness round about him.", "acv": "And I saw as it were glowing metal, as the appearance of fire within it round about, from the appearance of his loins and upward. And from the appearance of his loins and downward I saw as it were the appearance of fire. And there was brightness round about him.", "anderson": "", "haweis": "", "noyes": "And I saw what had the appearance of bright brass, what had the appearance of fire round about within it, from the appearance of his loins and upward. And from the appearance of his loins downward I saw what had the appearance of fire, and its brightness was round about him.", "webster": "And I saw as the color of amber, as the appearance of fire around within it, from the appearance of his loins even upward, and from the appearance of his loins even downward, I saw as it were the appearance of fire, and it had brightness on all sides.", "vulgate": "et vidi quasi speciem electri velut aspectum ignis intrinsecus eius per circuitum a lumbis eius et desuper et a lumbis eius usque deorsum vidi quasi speciem ignis splendentis in circuitu;", "brenton": "And I saw as it were the resemblance of amber from the appearance of the loins and upwards, and from the appearance of the loins and under I saw an appearance of fire, and the brightness thereof round about."}}, {"v": 28, "ref": "1:28", "o": "כְּ/מַרְאֵ֣ה הַ/קֶּ֡שֶׁת אֲשֶׁר֩ יִֽהְיֶ֨ה בֶ/עָנָ֜ן בְּ/י֣וֹם הַ/גֶּ֗שֶׁם כֵּ֣ן מַרְאֵ֤ה הַ/נֹּ֨גַהּ֙ סָבִ֔יב ה֕וּא מַרְאֵ֖ה דְּמ֣וּת כְּבוֹד יְהוָ֑ה וָֽ/אֶרְאֶה֙ וָ/אֶפֹּ֣ל עַל פָּנַ֔/י וָ/אֶשְׁמַ֖ע ק֥וֹל מְדַבֵּֽר", "en": {"kjv": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of the Lord. And when I saw it, I fell upon my face, and I heard a voice of one that spake.", "web": "As the appearance of the rainbow that is in the cloud in the day of rain, so was the appearance of the brightness all around. This was the appearance of the likeness of Yahweh’s glory. When I saw it, I fell on my face, and I heard a voice of one that spoke.", "bsb": "The appearance of the brilliant light all around Him was like that of a rainbow in a cloud on a rainy day. This was the appearance of the likeness of the glory of the LORD. And when I saw it, I fell facedown and heard a voice speaking.", "asv": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of Jehovah. And when I saw it, I fell upon my face, and I heard a voice of one that spake.", "ylt": "As the appearance of the bow that is in a cloud in a day of rain, so is the appearance of the brightness round about.", "dra": "As the appearance of the rainbow when it is in a cloud on a rainy day: this was the appearance of the brightness round about.", "bbe": "Like the bow in the cloud on a day of rain, so was the light shining round him. And this is what the glory of the Lord was like. And when I saw it I went down on my face, and the voice of one talking came to my ears.", "geneva": "As the likenesse of the bowe, that is in the cloude in the day of raine, so was the appearance of the light round about. This was the appearance of the similitude of the glorie of the Lord: and when I sawe it, I fell vpon my face, and I heard a voyce of one that spake.", "wycliffe": "as the biholdynge of the reynbowe, whanne it is in the cloude in the dai of reyn. This was the biholdyng of schynyng bi cumpas.", "rotherham": "as the appearance of the bow which is in a cloud on a day of rain, so was the appearance of the brightness round about, that was the appearance of the likeness of the glory of Yahweh, and when I saw, I fell upon my face, and heard a voice of one speaking.", "darby": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of Jehovah. And when I saw, I fell on my face, and I heard a voice of one that spoke.", "twenty": "", "jps": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of HaShem. And when I saw it, I fell upon my face, and I heard a voice of one that spoke.", "acv": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of Jehovah. And when I saw it, I fell upon my face, and I heard a voice speaking.", "anderson": "", "haweis": "", "noyes": "As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the glory of Jehovah. And when I saw it I fell upon my face, and I heard the voice of one who spoke.", "webster": "As the appearance of the bow that is in the cloud in the day of rain, so [was] the appearance of the brightness around. This [was] the appearance of the likeness of the glory of the LORD. And when I saw [it], I fell upon my face, and I heard a voice of one speaking.", "vulgate": "velut aspectum arcus cum fuerit in nube in die pluviae hic erat aspectus splendoris per gyrum;", "brenton": "As the appearance of the bow when it is in the cloud in days of rain, so was the form of brightness round about."}}]}, {"c": 2, "verses": [{"v": 1, "ref": "2:1", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י בֶּן אָדָם֙ עֲמֹ֣ד עַל רַגְלֶ֔י/ךָ וַ/אֲדַבֵּ֖ר אֹתָֽ/ךְ", "en": {"kjv": "And he said unto me, Son of man, stand upon thy feet, and I will speak unto thee.", "web": "He said to me, Son of man, stand on your feet, and I will speak with you.", "bsb": "“Son of man,” He said to me, “stand up on your feet and I will speak to you.”", "asv": "And he said unto me, Son of man, stand upon thy feet, and I will speak with thee.", "ylt": "It is the appearance of the likeness of the honour of Jehovah, and I see, and fall on my face, and I hear a voice speaking, and He saith unto me, `Son of man, stand on thy feet, and I speak with thee.'", "dra": "This was the vision of the likeness of the glory of the Lord, and I saw, and I fell upon my face, and I heard the voice of one that spoke, and he said to me: Son of man, stand upon thy feet, and I will speak to thee.", "bbe": "And he said to me, Son of man, get up on your feet, so that I may say words to you.", "geneva": "And he said vnto me, Sonne of man, stand vp vpon thy feete, and I wil speake vnto thee.", "wycliffe": "This was a siyt of the licnesse of the glorie of the Lord. And Y siy, and felle doun on my face; and Y herde the vois of a spekere. And he seide to me, Thou, sone of man, stonde on thi feet, and Y schal speke with thee.", "rotherham": "And he said unto me,—Son of man, Stand upon thy feet, that I may, speak with thee.", "darby": "And he said unto me, Son of man, stand upon thy feet, and I will speak with thee.", "twenty": "", "jps": "And He said unto me: 'Son of man, stand upon thy feet, and I will speak with thee.'", "acv": "And he said to me, Son of man, stand upon thy feet, and I will speak with thee.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, stand upon thy feet, and I will speak with thee.", "webster": "And he said to me, Son of man, stand upon thy feet, and I will speak to thee.", "vulgate": "haec visio similitudinis gloriae Domini et vidi et cecidi in faciem meam et audivi vocem loquentis et dixit ad me fili hominis sta supra pedes tuos et loquar tecum;", "brenton": "This was the appearance of the likeness of the glory of the Lord. And I saw and fell upon my face, and heard the voice of one speaking: and he said to me, Son of man, stand upon thy feet, and I will speak to thee."}}, {"v": 2, "ref": "2:2", "o": "וַ/תָּ֧בֹא בִ֣/י ר֗וּחַ כַּֽ/אֲשֶׁר֙ דִּבֶּ֣ר אֵלַ֔/י וַ/תַּעֲמִדֵ֖/נִי עַל רַגְלָ֑/י וָ/אֶשְׁמַ֕ע אֵ֖ת מִדַּבֵּ֥ר אֵלָֽ/י", "en": {"kjv": "And the spirit entered into me when he spake unto me, and set me upon my feet, that I heard him that spake unto me.", "web": "The Spirit entered into me when he spoke to me, and set me on my feet; and I heard him who spoke to me.", "bsb": "And as He spoke to me, the Spirit entered me and set me on my feet, and I heard Him speaking to me.", "asv": "And the Spirit entered into me when he spake unto me, and set me upon my feet; and I heard him that spake unto me.", "ylt": "And there doth come into me a spirit, when He hath spoken unto me, and it causeth me to stand on my feet, and I hear Him who is speaking unto me.", "dra": "And the spirit entered into me after that he spoke to me, and he set me upon my feet: and I heard him speaking to me,", "bbe": "And at his words the spirit came into me and put me on my feet; and his voice came to my ears.", "geneva": "And the Spirite entred into me, when he had spoken vnto me, and set me vpon my feete, so that I heard him that spake vnto me.", "wycliffe": "And the spirit entride in to me, after that he spak to me, and settide me on my feet. And Y herde oon spekynge to me,", "rotherham": "Then the Spirit entered into me as soon as he spake unto me, and it caused me to stand upon my feet,—and I heard one speaking unto me.", "darby": "And the Spirit entered into me when he spoke unto me, and set me upon my feet; and I heard him that spoke unto me.", "twenty": "", "jps": "And spirit entered into me when He spoke unto me, and set me upon my feet; and I heard Him that spoke unto me.", "acv": "And the Spirit entered into me when he spoke to me, and set me upon my feet. And I heard him who spoke to me.", "anderson": "", "haweis": "", "noyes": "And the spirit entered into me when he spoke to me, and set me upon my feet; and I heard him that spake with me.", "webster": "And the spirit entered into me when he spoke to me, and set me upon my feet, that I heard him that spoke to me.", "vulgate": "et ingressus est in me spiritus postquam locutus est mihi et statuit me supra pedes meos et audivi loquentem ad me;", "brenton": "And the Spirit came upon me, and took me up, and raised me, and set me on my feet: and I heard him speaking to me."}}, {"v": 3, "ref": "2:3", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י בֶּן אָדָם֙ שׁוֹלֵ֨חַ אֲנִ֤י אֽוֹתְ/ךָ֙ אֶל בְּנֵ֣י יִשְׂרָאֵ֔ל אֶל גּוֹיִ֥ם הַ/מּוֹרְדִ֖ים אֲשֶׁ֣ר מָרְדוּ בִ֑/י הֵ֤מָּה וַ/אֲבוֹתָ/ם֙ פָּ֣שְׁעוּ בִ֔/י עַד עֶ֖צֶם הַ/יּ֥וֹם הַ/זֶּֽה", "en": {"kjv": "And he said unto me, Son of man, I send thee to the children of Israel, to a rebellious nation that hath rebelled against me: they and their fathers have transgressed against me, even unto this very day.", "web": "He said to me, Son of man, I send you to the children of Israel, to a nation of rebels who have rebelled against me. They and their fathers have transgressed against me even to this very day.", "bsb": "“Son of man,” He said to me, “I am sending you to the Israelites, to a rebellious nation that has rebelled against Me. To this very day they and their fathers have rebelled against Me.", "asv": "And he said unto me, Son of man, I send thee to the children of Israel, to nations that are rebellious, which have rebelled against me: they and their fathers have transgressed against me even unto this very day.", "ylt": "And He saith unto Me, `Son of man, I am sending thee unto the sons of Israel, unto nations who are rebels, who have rebelled against Me; they and their fathers have transgressed against Me, unto this self-same day.", "dra": "And saying: Son of man, I send thee to the children of Israel, to a rebellious people, that hath revolted from me, they, and their fathers, have transgressed my covenant even unto this day.", "bbe": "And he said to me, Son of man, I am sending you to the children of Israel, to an uncontrolled nation which has gone against me: they and their fathers have been sinners against me even to this very day.", "geneva": "And he said vnto me, Sonne of man, I send thee to the children of Israel, to a rebellious nation that hath rebelled against me: for they and their fathers haue rebelled against me, euen vnto this very day.", "wycliffe": "and seiynge, Sone of man, Y sende thee to the sones of Israel, to folkis apostatas, `ether goynge a bak fro feith, that yeden awei fro me; the fadris of hem braken my couenaunt til to this dai.", "rotherham": "And he said unto me- Son of man I am sending thee unto the sons of Israel, unto rebellious nations, which have rebelled against me,—they, and their fathers have transgressed against me, until this very day;", "darby": "And he said unto me, Son of man, I send thee to the children of Israel, to nations that are rebellious, which have rebelled against me: they and their fathers have transgressed against me unto this very day;", "twenty": "", "jps": "And He said unto me: 'Son of man, I send thee to the children of Israel, to rebellious nations, that have rebelled against Me; they and their fathers have transgressed against Me, even unto this very day;", "acv": "And he said to me, Son of man, I send thee to the sons of Israel, to nations that are rebellious, which have rebelled against me. They and their fathers have transgressed against me even to this very day.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, I send thee to the sons of Israel, to a rebellious nation, that hath rebelled against me; they and their fathers have rebelled against me to this very day.", "webster": "And he said to me, Son of man, I send thee to the children of Israel, to a rebellious nation that hath rebelled against me: they and their fathers have transgressed against me: [even] to this very day.", "vulgate": "et dicentem fili hominis mitto ego te ad filios Israhel ad gentes apostatrices quae recesserunt a me patres eorum praevaricati sunt pactum meum usque ad diem hanc;", "brenton": "And he said to me, Son of Man, I send thee forth to the house of Israel, them that provoke me; who have provoked me, they and their fathers to this day."}}, {"v": 4, "ref": "2:4", "o": "וְ/הַ/בָּנִ֗ים קְשֵׁ֤י פָנִים֙ וְ/חִזְקֵי לֵ֔ב אֲנִ֛י שׁוֹלֵ֥חַ אוֹתְ/ךָ֖ אֲלֵי/הֶ֑ם וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "For they are impudent children and stiffhearted. I do send thee unto them; and thou shalt say unto them, Thus saith the Lord God.", "web": "The children are impudent and stiff-hearted: I am sending you to them; and you shall tell them, Thus says the Lord Yahweh.", "bsb": "They are obstinate and stubborn children. I am sending you to them, and you are to say to them, ‘This is what the Lord GOD says.’", "asv": "And the children are impudent and stiffhearted: I do send thee unto them; and thou shalt say unto them, Thus saith the Lord Jehovah.", "ylt": "And the sons are brazen-faced and hard-hearted to whom I am sending thee, and thou hast said unto them: Thus said the Lord Jehovah:", "dra": "And they to whom I send thee are children of a hard face, and of an obstinate heart: and thou shalt say to them: Thus saith the Lord God:", "bbe": "And the children are hard and stiff-hearted; I am sending you to them: and you are to say to them, These are the words of the Lord.", "geneva": "For they are impudent children, and stiffe hearted: I do send thee vnto them, and thou shalt say vnto them, Thus saith the Lord God.", "wycliffe": "And the sones ben of hard face, and of vnchastisable herte, to whiche Y sende thee. And thou schalt seie to hem, The Lord God seith these thingis;", "rotherham": "and it is unto such sons—of shameless face, and emboldened heart, that I am sending thee,—therefore shalt thou say unto them, Thus saith My Lord, Yahweh.", "darby": "and these children are impudent and hard-hearted: I am sending thee unto them; and thou shalt say unto them, Thus saith the Lord Jehovah.", "twenty": "", "jps": "and the children are brazen-faced and stiff-hearted, I do send thee unto them; and thou shalt say unto them: Thus saith the L-rd GOD.", "acv": "And the sons are impudent and stiff hearted. I send thee to them, and thou shall say to them, Thus says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Brazen-faced and stiff-hearted are the sons to whom I send thee. And thou shalt say to them, Thus saith the Lord Jehovah.", "webster": "For [they are] impudent children and obstinate in heart. I send thee to them; and thou shalt say to them, Thus saith the Lord GOD.", "vulgate": "et filii dura facie et indomabili corde sunt ad quos ego mitto te et dices ad eos haec dicit Dominus Deus;", "brenton": "And thou shalt say to them, Thus saith the Lord."}}, {"v": 5, "ref": "2:5", "o": "וְ/הֵ֨מָּה֙ אִם יִשְׁמְע֣וּ וְ/אִם יֶחְדָּ֔לוּ כִּ֛י בֵּ֥ית מְרִ֖י הֵ֑מָּה וְ/יָ֣דְע֔וּ כִּ֥י נָבִ֖יא הָיָ֥ה בְ/תוֹכָֽ/ם", "en": {"kjv": "And they, whether they will hear, or whether they will forbear, (for they are a rebellious house,) yet shall know that there hath been a prophet among them.", "web": "They, whether they will hear, or whether they will forbear, (for they are a rebellious house), yet shall know that there has been a prophet among them.", "bsb": "And whether they listen or refuse to listen—for they are a rebellious house—they will know that a prophet has been among them.", "asv": "And they, whether they will hear, or whether they will forbear (for they are a rebellious house), yet shall know that there hath been a prophet among them.", "ylt": "and they--whether they hear, or whether they forbear, for a rebellious house they are --have known that a prophet hath been in their midst.", "dra": "If so be they at least will hear, and if so be they will forbear, for they are a provoking house: and they shall know that there hath been a prophet in the midst of them.", "bbe": "And they, if they give ear to you or if they do not give ear (for they are an uncontrolled people), will see that there has been a prophet among them.", "geneva": "But surely they will not heare, neither in deede will they cease: for they are a rebellious house: yet shall they knowe that there hath bene a Prophet among them.", "wycliffe": "if perauenture nameli thei heren, and if perauenture thei resten, for it is an hous terrynge to wraththe. And thei schulen wite, that a profete is in the myddis of hem.", "rotherham": "And they! whether they will hear or whether they will forbear, for a perverse house, they are, shall then know that, a prophet, hath been in their midst.", "darby": "And they, whether they will hear or whether they will forbear — for they are a rebellious house — yet shall they know that there hath been a prophet among them.", "twenty": "", "jps": "And they, whether they will hear, or whether they will forbear--for they are a rebellious house--yet shall know that there hath been a prophet among them.", "acv": "And they, whether they will hear, or whether they will forbear (for they are a rebellious house), yet shall know that there has been a prophet among them.", "anderson": "", "haweis": "", "noyes": "And whether they will hear, or whether they will forbear, for they are a rebellious house, yet shall they know that a prophet is in the midst of them.", "webster": "And they, whether they will hear, or whether they will forbear, (for they [are] a rebellious house,) yet shall know that there hath been a prophet among them.", "vulgate": "si forte vel ipsi audiant et si forte quiescant quoniam domus exasperans est et scient quia propheta fuerit in medio eorum;", "brenton": "Whether then indeed they shall hear or fear, (for it is a provoking house,) yet they shall know that thou art a prophet in the midst of them."}}, {"v": 6, "ref": "2:6", "o": "וְ/אַתָּ֣ה בֶן אָ֠דָם אַל תִּירָ֨א מֵ/הֶ֜ם וּ/מִ/דִּבְרֵי/הֶ֣ם אַל תִּירָ֗א כִּ֣י סָרָבִ֤ים וְ/סַלּוֹנִים֙ אוֹתָ֔/ךְ וְ/אֶל עַקְרַבִּ֖ים אַתָּ֣ה יוֹשֵׁ֑ב מִ/דִּבְרֵי/הֶ֤ם אַל תִּירָא֙ וּ/מִ/פְּנֵי/הֶ֣ם אַל תֵּחָ֔ת כִּ֛י בֵּ֥ית מְרִ֖י הֵֽמָּה", "en": {"kjv": "And thou, son of man, be not afraid of them, neither be afraid of their words, though briers and thorns be with thee, and thou dost dwell among scorpions: be not afraid of their words, nor be dismayed at their looks, though they be a rebellious house.", "web": "You, son of man, don’t be afraid of them, neither be afraid of their words, though briers and thorns are with you, and you do dwell among scorpions: don’t be afraid of their words, nor be dismayed at their looks, though they are a rebellious house.", "bsb": "But you, son of man, do not be afraid of them or their words. Do not be afraid, though briers and thorns surround you, and you dwell among scorpions. Do not be afraid of their words or dismayed by their presence, though they are a rebellious house.", "asv": "And thou, son of man, be not afraid of them, neither be afraid of their words, though briers and thorns are with thee, and thou dost dwell among scorpions: be not afraid of their words, nor be dismayed at their looks, though they are a rebellious house.", "ylt": "`And thou, son of man, thou art not afraid of them, yea, of their words thou art not afraid, for briers and thorns are with thee, and near scorpions thou art dwelling, of their words thou art not afraid, and of their faces thou art not affrighted, for they are a rebellious house,", "dra": "And thou, O son of man, fear not, neither be thou afraid of their words: for thou art among unbelievers and destroyers, and thou dwellest with scorpions. Fear not their words, neither be thou dismayed at their looks: for they are a provoking house.", "bbe": "And you, son of man, have no fear of them or of their words, even if sharp thorns are round you and you are living among scorpions: have no fear of their words and do not be overcome by their looks, for they are an uncontrolled people.", "geneva": "And thou sonne of man, feare them not, neither be afraide of their wordes, although rebels, and thornes be with thee, and thou remainest with scorpions: feare not their wordes, nor be afrayde at their lookes, for they are a rebellious house.", "wycliffe": "Therfore thou, sone of man, drede not hem, nether drede thou the wordis of hem; for vnbileueful men and distrieris ben with thee, and thou dwellist with scorpiouns. Drede thou not the wordis of hem, and drede thou not the faces of hem, for it is an hous terrynge to wraththe.", "rotherham": "But thou son of man Be not afraid of them Nor of their words, be afraid Though thorns and thistles are about thee, And amongst prickly plants, thou dost dwell, Of their words, be not afraid nor At their faces, be thou dismayed, For a perverse house, they are!", "darby": "And thou, son of man, be not afraid of them, and be not afraid of their words; for briars and thorns are with thee, and thou dwellest among scorpions: be not afraid of their words, and be not dismayed at their faces; for they are a rebellious house.", "twenty": "", "jps": "And thou, son of man, be not afraid of them, neither be afraid of their words, though defiers and despisers be with thee, and thou dost dwell among scorpions; be not afraid of their words, nor be dismayed at their looks, for they are a rebellious house.", "acv": "And thou, son of man, be not afraid of them, nor be afraid of their words, though briers and thorns are with thee, and thou dwell among scorpions. Be not afraid of their words, nor be dismayed at their looks, though they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "And thou, son of man, be not afraid of them, and of their words be not afraid, though they be briers and thorns toward thee, and though thou dwell among scorpions; be not afraid of their words, nor be dismayed at their looks, for they are a rebellious house.", "webster": "And thou, son of man, be not afraid of them, neither be afraid of their words, though briers and thorns [are] with thee, and thou dost dwell among scorpions: be not afraid of their words, nor be dismayed at their looks, though they [are] a rebellious house.", "vulgate": "tu ergo fili hominis ne timeas eos neque sermones eorum metuas quoniam increduli et subversores sunt tecum et cum scorpionibus habitas verba eorum ne timeas et vultus eorum ne formides quia domus exasperans est;", "brenton": "And thou, son of man, fear them not, nor be dismayed at their face; (for they will madden and will rise up against thee round about, and thou dwellest in the midst of scorpions): be not afraid of their words, nor be dismayed at their countenance, for it is a provoking house."}}, {"v": 7, "ref": "2:7", "o": "וְ/דִבַּרְתָּ֤ אֶת דְּבָרַ/י֙ אֲלֵי/הֶ֔ם אִֽם יִשְׁמְע֖וּ וְ/אִם יֶחְדָּ֑לוּ כִּ֥י מְרִ֖י הֵֽמָּה", "en": {"kjv": "And thou shalt speak my words unto them, whether they will hear, or whether they will forbear: for they are most rebellious.", "web": "You shall speak my words to them, whether they will hear, or whether they will forbear; for they are most rebellious.", "bsb": "But speak My words to them, whether they listen or refuse to listen, for they are rebellious.", "asv": "And thou shalt speak my words unto them, whether they will hear, or whether they will forbear; for they are most rebellious.", "ylt": "And thou hast spoken My words unto them, whether they hear or whether they forbear, for they are rebellious.", "dra": "And thou shalt speak my words to them, if perhaps they will hear, and forbear: for they provoke me to anger.", "bbe": "And you are to give them my words, if they give ear to you or if they do not: for they are uncontrolled.", "geneva": "Therefore thou shalt speake my words vnto them: but surely they will not heare, neither will they in deede cease: for they are rebellious.", "wycliffe": "Therfor thou schalt speke my wordis to hem, if perauenture thei heren, and resten, for thei ben terreris to wraththe.", "rotherham": "Thou shalt therefore speak my words unto them, whether they will hear, or whether they will forbear For perverse, they are!", "darby": "And thou shalt speak my words unto them, whether they will hear or whether they will forbear; for they are rebellious.", "twenty": "", "jps": "And thou shalt speak My words unto them, whether they will hear, or whether they will forbear; for they are most rebellious.", "acv": "And thou shall speak my words to them, whether they will hear, or whether they will forbear, for they are most rebellious.", "anderson": "", "haweis": "", "noyes": "Speak thou my words to them, whether they will hear, or whether they will forbear, for they are most rebellious.", "webster": "And thou shalt speak my words to them, whether they will hear, or whether they will forbear: for they [are] most rebellious.", "vulgate": "loqueris ergo verba mea ad eos si forte audiant et quiescant quoniam inritatores sunt;", "brenton": "And thou shalt speak my words to them, whether they will hear or fear: for it is a provoking house."}}, {"v": 8, "ref": "2:8", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם שְׁמַע֙ אֵ֤ת אֲשֶׁר אֲנִי֙ מְדַבֵּ֣ר אֵלֶ֔י/ךָ אַל תְּהִי מֶ֖רִי כְּ/בֵ֣ית הַ/מֶּ֑רִי פְּצֵ֣ה פִ֔י/ךָ וֶ/אֱכֹ֕ל אֵ֥ת אֲשֶׁר אֲנִ֖י נֹתֵ֥ן אֵלֶֽי/ךָ", "en": {"kjv": "But thou, son of man, hear what I say unto thee; Be not thou rebellious like that rebellious house: open thy mouth, and eat that I give thee.", "web": "But you, son of man, hear what I tell you; don’t be rebellious like that rebellious house: open your mouth, and eat that which I give you.", "bsb": "And you, son of man, listen to what I tell you. Do not be rebellious like that rebellious house. Open your mouth and eat what I give you.”", "asv": "But thou, son of man, hear what I say unto thee; be not thou rebellious like that rebellious house: open thy mouth, and eat that which I give thee.", "ylt": "`And thou, son of man, hear that which I am speaking unto thee: Thou art not rebellious like the rebellious house, open thy mouth, and eat that which I am giving unto thee.'", "dra": "But thou, O son of man, hear all that I say to thee: and do not thou provoke me, as that house provoketh me: open thy mouth, and eat what I give thee.", "bbe": "But you, son of man, give ear to what I say to you, and do not be uncontrolled like that uncontrolled people: let your mouth be open and take what I give you.", "geneva": "But thou sonne of man, heare what I say vnto thee: be not thou rebellious, like this rebellious house: open thy mouth, and eate that I giue thee.", "wycliffe": "But thou, sone of man, here what euer thingis Y schal speke to thee; and nyle thou be a terrere to wraththe, as the hows of Israel is a terrere to wraththe. Opene thi mouth, and ete what euer thingis Y yyue to thee.", "rotherham": "Thou, therefore son of man, hear what I am speaking unto thee., become not perverse like the perverse house,—open thy mouth, and eat that which I am giving unto thee.", "darby": "And thou, son of man, hear what I say unto thee; be not thou rebellious like that rebellious house: open thy mouth, and eat that I give thee.", "twenty": "", "jps": "And thou, son of man, hear what I say unto thee: be not thou rebellious like that rebellious house; open thy mouth, and eat that which I give thee.'", "acv": "But thou, son of man, hear what I say to thee. Be not thou rebellious like that rebellious house. Open thy mouth, and eat that which I give thee.", "anderson": "", "haweis": "", "noyes": "But thou, son of man, hear what I say to thee! Be not thou rebellious, like that rebellious house. Open thy mouth, and eat that which I give thee.", "webster": "But thou, son of man, hear what I say to thee; Be not thou rebellious like that rebellious house: open thy mouth, and eat that which I give thee.", "vulgate": "tu autem fili hominis audi quaecumque loquor ad te et noli esse exasperans sicut domus exasperatrix est aperi os tuum et comede quaecumque ego do tibi;", "brenton": "And thou, son of man, hear him that speaks to thee; be not thou provoking, as the provoking house: open thy mouth, and eat what I give thee."}}, {"v": 9, "ref": "2:9", "o": "וָ/אֶרְאֶ֕ה וְ/הִנֵּה יָ֖ד שְׁלוּחָ֣ה אֵלָ֑/י וְ/הִנֵּה ב֖/וֹ מְגִלַּת סֵֽפֶר", "en": {"kjv": "And when I looked, behold, an hand was sent unto me; and, lo, a roll of a book was therein;", "web": "When I looked, behold, a hand was stretched out to me; and, behold, a scroll of a book was therein;", "bsb": "Then I looked and saw a hand reaching out to me, and in it was a scroll,", "asv": "And when I looked, behold, a hand was put forth unto me; and, lo, a roll of a book was therein;", "ylt": "And I look, and lo, a hand is sent forth unto me, and lo, in it a roll of a book,", "dra": "And I looked, and behold, a hand was sent to me, wherein was a book rolled up: and he spread it before me, and it was written within and without: and there were written in it lamentations, and canticles, and woe.", "bbe": "And looking, I saw a hand stretched out to me, and I saw the roll of a book in it;", "geneva": "And when I looked vp, beholde, an hande was sent vnto me, and loe, a roule of a booke was therein.", "wycliffe": "And Y siy, and lo! an hond was sent to me, in which a book was foldid togidere. And he spredde abrood it bifor me, that was writun with ynne and with outforth. And lamentaciouns, and song, and wo, weren writun ther ynne.", "rotherham": "So I looked, and lo! a hand put forth unto me,—and lo! therein a scroll;", "darby": "And I looked, and behold, a hand was put forth toward me; and behold, a roll of a book therein.", "twenty": "", "jps": "And when I looked, behold, a hand was put forth unto me; and, lo, a roll of a book was therein;", "acv": "And when I looked, behold, a hand was put forth to me, and, lo, a roll of a book was in it,", "anderson": "", "haweis": "", "noyes": "And when I looked, behold, a hand was put forth to me; and lo, a book-roll was therein.", "webster": "And when I looked, behold, a hand [was] sent to me; and lo, a roll of a book [was] in it;", "vulgate": "et vidi et ecce manus missa ad me in qua erat involutus liber et expandit illum coram me qui erat scriptus intus et foris et scriptae erant in eo lamentationes et carmen et vae;", "brenton": "And I looked, and behold, a hand stretched out to me, and in it a volume of a book."}}, {"v": 10, "ref": "2:10", "o": "וַ/יִּפְרֹ֤שׂ אוֹתָ/הּ֙ לְ/פָנַ֔/י וְ/הִ֥יא כְתוּבָ֖ה פָּנִ֣ים וְ/אָח֑וֹר וְ/כָת֣וּב אֵלֶ֔י/הָ קִנִ֥ים וָ/הֶ֖גֶה וָ/הִֽי", "en": {"kjv": "And he spread it before me; and it was written within and without: and there was written therein lamentations, and mourning, and woe.", "web": "He spread it before me: and it was written within and without; and there were written therein lamentations, and mourning, and woe.", "bsb": "which He unrolled before me. And written on the front and back of it were words of lamentation, mourning, and woe.", "asv": "and he spread it before me: and it was written within and without; and there were written therein lamentations, and mourning, and woe.", "ylt": "and He spreadeth it before me, and it is written in front and behind, and written on it are lamentations, and mourning, and woe!", "dra": "", "bbe": "And he put it open before me, and it had writing on the front and on the back; words of grief and sorrow and trouble were recorded in it.", "geneva": "And he spred it before me, and it was written within and without, and there was written therein, Lamentations, and mourning, and woe.", "wycliffe": "", "rotherham": "and he spread it out before me, and, it was written on the front and the back,—and there were written thereon, lamentation and sighing, and wailing.", "darby": "And he spread it out before me; and it was written within and without; and there were written in it lamentations, and mourning, and woe.", "twenty": "", "jps": "and He spread it before me, and it was written within and without; and there was written therein lamentations, and moaning, and woe.", "acv": "And he spread it before me, and it was written inside and outside. And there were written in it lamentations and mourning and woe.", "anderson": "", "haweis": "", "noyes": "And he spread it before me, and it was written within and without. And therein was written lamentation and mourning and woe.", "webster": "And he spread it before me: and it [was] written within and without: and [there was] written in it lamentations, and mourning, and woe.", "vulgate": "", "brenton": "And he unrolled it before me: and in it the front and the back were written upon: and there was written in it Lamentation, and mournful song, and woe."}}]}, {"c": 3, "verses": [{"v": 1, "ref": "3:1", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י בֶּן אָדָ֕ם אֵ֥ת אֲשֶׁר תִּמְצָ֖א אֱכ֑וֹל אֱכוֹל֙ אֶת הַ/מְּגִלָּ֣ה הַ/זֹּ֔את וְ/לֵ֥ךְ דַּבֵּ֖ר אֶל בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Moreover he said unto me, Son of man, eat that thou findest; eat this roll, and go speak unto the house of Israel.", "web": "He said to me, Son of man, eat that which you find. Eat this scroll, and go, speak to the house of Israel.", "bsb": "“Son of man,” He said to me, “eat what you find here. Eat this scroll, then go and speak to the house of Israel.”", "asv": "And he said unto me, Son of man, eat that which thou findest; eat this roll, and go, speak unto the house of Israel.", "ylt": "And He saith unto me, `Son of man, that which thou findest eat, eat this roll, and go, speak unto the house of Israel.'", "dra": "And he said to me: Son of man, eat all that thou shalt find: eat this book, and go speak to the children of Israel.", "bbe": "And he said to me, Son of man, take this roll for your food, and go and say my words to the children of Israel.", "geneva": "Moreover he saide vnto me, Sonne of man, eate that thou findest: eate this roule, and goe, and speake vnto the house of Israel.", "wycliffe": "And he seide to me, Sone of man, ete thou what euer thing thou fyndist, ete thou this volym; and go thou, and speke to the sones of Israel.", "rotherham": "Then said he unto me, Son of man What thou findest, eat,—eat this roll, and go speak unto the house of Israel.", "darby": "And he said unto me, Son of man, eat what thou findest; eat this roll, and go, speak unto the house of Israel.", "twenty": "", "jps": "And He said unto me: 'Son of man, eat that which thou findest; eat this roll, and go, speak unto the house of Israel.'", "acv": "And he said to me, Son of man, eat that which thou find. Eat this roll, and go, speak to the house of Israel.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, eat that which thou findest; eat this roll, and go, speak to the house of Israel!", "webster": "Moreover he said to me, Son of man, eat what thou findest; eat this roll, and go, speak to the house of Israel.", "vulgate": "et dixit ad me fili hominis quodcumque inveneris comede comede volumen istud et vadens loquere ad filios Israhel;", "brenton": "And he said to me, Son of Man, eat this volume, and go and speak to the children of Israel."}}, {"v": 2, "ref": "3:2", "o": "וָ/אֶפְתַּ֖ח אֶת פִּ֑/י וַ/יַּ֣אֲכִלֵ֔/נִי אֵ֖ת הַ/מְּגִלָּ֥ה הַ/זֹּֽאת", "en": {"kjv": "So I opened my mouth, and he caused me to eat that roll.", "web": "So I opened my mouth, and he caused me to eat the scroll.", "bsb": "So I opened my mouth, and He fed me the scroll.", "asv": "So I opened my mouth, and he caused me to eat the roll.", "ylt": "And I open my mouth, and He causeth me to eat this roll.", "dra": "And I opened my mouth, and he caused me to eat that book:", "bbe": "And, on my opening my mouth, he made me take the roll as food.", "geneva": "So I opened my mouth, and he gaue mee this roule to eate.", "wycliffe": "And Y openyde my mouth, and he fedde me with that volym.", "rotherham": "So I opened my mouth,—and he caused me to eat this roll.", "darby": "So I opened my mouth, and he caused me to eat that roll.", "twenty": "", "jps": "So I opened my mouth, and He caused me to eat that roll.", "acv": "So I opened my mouth, and he caused me to eat the roll.", "anderson": "", "haweis": "", "noyes": "So I opened my mouth, and he gave me the roll to eat.", "webster": "So I opened my mouth, and he caused me to eat that roll.", "vulgate": "et aperui os meum et cibavit me volumine illo;", "brenton": "So he opened my mouth, and caused me to eat the volume. And he said to me, Son of man,"}}, {"v": 3, "ref": "3:3", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י בֶּן אָדָם֙ בִּטְנְ/ךָ֤ תַֽאֲכֵל֙ וּ/מֵעֶ֣י/ךָ תְמַלֵּ֔א אֵ֚ת הַ/מְּגִלָּ֣ה הַ/זֹּ֔את אֲשֶׁ֥ר אֲנִ֖י נֹתֵ֣ן אֵלֶ֑י/ךָ וָ/אֹ֣כְלָ֔/ה וַ/תְּהִ֥י בְּ/פִ֖/י כִּ/דְבַ֥שׁ לְ/מָתֽוֹק", "en": {"kjv": "And he said unto me, Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee. Then did I eat it; and it was in my mouth as honey for sweetness.", "web": "He said to me, Son of man, cause your belly to eat, and fill your bowels with this scroll that I give you. Then I ate it; and it was as sweet as honey in my mouth.", "bsb": "“Son of man,” He said to me, “eat and fill your stomach with this scroll I am giving you.” So I ate, and it was as sweet as honey in my mouth.", "asv": "And he said unto me, Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee. Then did I eat it; and it was in my mouth as honey for sweetness.", "ylt": "And He saith unto me, `Son of man, thy belly thou dost feed, and thy bowels thou dost fill with this roll that I am giving unto thee;' and I eat it, and it is in my mouth as honey for sweetness.", "dra": "And he said to me: Son of man, thy belly shall eat, and thy bowels shall be filled with this book, which I give thee, and I did eat it: and it was sweet as honey in my mouth.", "bbe": "And he said to me, Son of man, let your stomach make a meal of it and let your inside be full of this roll which I am giving you. Then I took it, and it was sweet as honey in my mouth.", "geneva": "And he said vnto me, Sonne of man, cause thy belly to eate, and fill thy bowels with this roule that I giue thee. Then did I eate it, and it was in my mouth as sweete as honie.", "wycliffe": "And he seide to me, Sone of man, thi wombe schal ete, and thin entrails schulen be fillid with this volym, which Y yyue to thee. And Y eet it, and it was maad as swete hony in my mouth.", "rotherham": "Then said he unto me Son of man. Thy belly, cause thou to eat and thy bowels, fill thou with this roll which I am giving unto thee. So I did eat, and it became in my mouth, as honey for sweetness.", "darby": "And he said unto me, Son of man, cause thy belly to eat, and fill thy bowels with this roll which I give thee. And I ate, and it was in my mouth as honey for sweetness.", "twenty": "", "jps": "And He said unto me: 'Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee.' Then did I eat it; and it was in my mouth as honey for sweetness.", "acv": "And he said to me, Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee. Then I ate it, and it was in my mouth as honey for sweetness.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, let thy stomach eat, and fill thy body with this roll which I give thee! Then I ate it, and it was in my mouth as honey for sweetness.", "webster": "And he said to me, Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee. Then did I eat [it]; and it was in my mouth as honey for sweetness.", "vulgate": "et dixit ad me fili hominis venter tuus comedet et viscera tua conplebuntur volumine isto quod ego do tibi et comedi illud et factum est in ore meo sicut mel dulce;", "brenton": "thy mouth shall eat, and thy belly shall be filled with this volume that is given to thee. So I ate it; and it was in my mouth as sweet as honey."}}, {"v": 4, "ref": "3:4", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י בֶּן אָדָ֗ם לֶךְ בֹּא֙ אֶל בֵּ֣ית יִשְׂרָאֵ֔ל וְ/דִבַּרְתָּ֥ בִ/דְבָרַ֖/י אֲלֵי/הֶֽם", "en": {"kjv": "And he said unto me, Son of man, go, get thee unto the house of Israel, and speak with my words unto them.", "web": "He said to me, Son of man, go to the house of Israel, and speak my words to them.", "bsb": "Then He said to me, “Son of man, go now to the house of Israel and speak My words to them.", "asv": "And he said unto me, Son of man, go, get thee unto the house of Israel, and speak with my words unto them.", "ylt": "And He saith unto me, `Son of man, go, enter in unto the house of Israel, and thou hast spoken with My words unto them.", "dra": "And he said to me: Son of man, go to the house of Israel, and thou shalt speak my words to them.", "bbe": "And he said to me, Son of man, go now to the children of Israel, and say my words to them.", "geneva": "And he said vnto me, Sonne of man, goe, and enter into the house of Israel, and declare them my wordes.", "wycliffe": "And he seide to me, Sone of man, go thou to the hous of Israel, and thou schalt speke my wordis to hem.", "rotherham": "Then said he unto me,— Son of man Go get thee unto the house of Israel, and thou shalt speak with my words, unto them.", "darby": "And he said unto me, Son of man, go, get thee unto the house of Israel, and speak with my words unto them.", "twenty": "", "jps": "And He said unto me: 'Son of man, go, get thee unto the house of Israel, and speak with My words unto them.", "acv": "And he said to me, Son of man, go, get thee to the house of Israel, and speak to them with my words.", "anderson": "", "haweis": "", "noyes": "And he said to me: Son of man, go, get thee to the house of Israel, and speak my words to them!", "webster": "And he said to me, Son of man, depart, go to the house of Israel, and speak with my words to them.", "vulgate": "et dixit ad me fili hominis vade ad domum Israhel et loqueris verba mea ad eos;", "brenton": "And he said to me, Son of man, go thy way, and go in to the house of Israel, and speak my words to them."}}, {"v": 5, "ref": "3:5", "o": "כִּ֡י לֹא֩ אֶל עַ֨ם עִמְקֵ֥י שָׂפָ֛ה וְ/כִבְדֵ֥י לָשׁ֖וֹן אַתָּ֣ה שָׁל֑וּחַ אֶל בֵּ֖ית יִשְׂרָאֵֽל", "en": {"kjv": "For thou art not sent to a people of a strange speech and of an hard language, but to the house of Israel;", "web": "For you are not sent to a people of a strange speech and of a hard language, but to the house of Israel;", "bsb": "For you are not being sent to a people of unfamiliar speech or difficult language, but to the house of Israel—", "asv": "For thou art not sent to a people of a strange speech and of a hard language, but to the house of Israel;", "ylt": "For, not unto a people deep of lip and heavy of tongue art thou sent--unto the house of Israel;", "dra": "For thou art not sent to a people of a profound speech, and of an unknown tongue, but to the house of Israel:", "bbe": "For you are not sent to a people whose talk is strange and whose language is hard, but to the children of Israel;", "geneva": "For thou art not sent to a people of an vnknowen tongue, or of an hard language, but to the house of Israel,", "wycliffe": "For thou schalt not be sent to a puple of hiy word, and of vnknowun langage; thou schalt be sent to the hous of Israel,", "rotherham": "For not unto a people deep of lip and heavy of tongue, art thou sent —[but] unto the house of Israel:", "darby": "For thou art not sent to a people of strange language, and of difficult speech, [but] to the house of Israel;", "twenty": "", "jps": "For thou art not sent to a people of an unintelligible speech and of a slow tongue, but to the house of Israel;", "acv": "For thou are not sent to a people of a strange speech and of a hard language, but to the house of Israel,", "anderson": "", "haweis": "", "noyes": "For not to a people of a dark speech and a hard language art thou sent, but to the house of Israel;", "webster": "For thou art not sent to a people of a strange speech and of a hard language, [but] to the house of Israel;", "vulgate": "non enim ad populum profundi sermonis et ignotae linguae tu mitteris ad domum Israhel;", "brenton": "For thou art not sent to a people of hard speech, but to the house of Israel;"}}, {"v": 6, "ref": "3:6", "o": "לֹ֣א אֶל עַמִּ֣ים רַבִּ֗ים עִמְקֵ֤י שָׂפָה֙ וְ/כִבְדֵ֣י לָשׁ֔וֹן אֲשֶׁ֥ר לֹֽא תִשְׁמַ֖ע דִּבְרֵי/הֶ֑ם אִם לֹ֤א אֲלֵי/הֶם֙ שְׁלַחְתִּ֔י/ךָ הֵ֖מָּה יִשְׁמְע֥וּ אֵלֶֽי/ךָ", "en": {"kjv": "Not to many people of a strange speech and of an hard language, whose words thou canst not understand. Surely, had I sent thee to them, they would have hearkened unto thee.", "web": "not to many peoples of a strange speech and of a hard language, whose words you can not understand. Surely, if I sent you to them, they would listen to you.", "bsb": "not to the many peoples of unfamiliar speech and difficult language whose words you cannot understand. Surely if I had sent you to them, they would have listened to you.", "asv": "not to many peoples of a strange speech and of a hard language, whose words thou canst not understand. Surely, if I sent thee to them, they would hearken unto thee.", "ylt": "not unto many peoples, deep of lip and heavy of tongue, whose words thou dost not understand. If I had not sent thee unto them--they, they do hearken unto thee,", "dra": "Nor to many nations of a strange speech, and of an unknown tongue, whose words thou canst not understand: and if thou wert sent to them, they would hearken to thee.", "bbe": "Not to a number of peoples whose talk is strange and whose language is hard and whose words are not clear to you. Truly, if I sent you to them they would give ear to you.", "geneva": "Not to many people of an vnknowen tongue, or of an harde language, whose wordes thou canst not vnderstand: yet if I should sende thee to them, they would obey thee.", "wycliffe": "nether to many puplis of hiy word, and of vnknowun langage, of whiche thou maist not here the wordis. And if thou were sent to hem, thei schulden here thee.", "rotherham": "not unto many peoples deep of lip and heavy of tongue, whose words thou couldst not understand,—surely if unto them I had sent thee, they would have hearkened unto thee.", "darby": "not to many peoples of strange language and of difficult speech, whose words thou canst not understand: had I sent thee to them, would they not hearken unto thee?", "twenty": "", "jps": "not to many peoples of an unintelligible speech and of a slow tongue, whose words thou canst not understand. Surely, if I sent thee to them, they would hearken unto thee.", "acv": "not to many peoples of a strange speech, and of a hard language, whose words thou cannot understand. Surely, if I sent thee to them, they would hearken to thee.", "anderson": "", "haweis": "", "noyes": "not to many nations of a dark speech and a hard language, whose words thou canst not understand. Truly, had I sent thee to them, they would have hearkened to thee.", "webster": "Not to many people of a strange speech and of a hard language, whose words thou canst not understand. Surely, had I sent thee to them, they would have hearkened to thee.", "vulgate": "neque ad populos multos profundi sermonis et ignotae linguae quorum non possis audire sermones et si ad illos mittereris ipsi audirent te;", "brenton": "neither to many nations of other speech and other tongues, nor of harsh language, whose words thou wouldest not understand: although if I had sent thee to such, they would have hearkened to thee."}}, {"v": 7, "ref": "3:7", "o": "וּ/בֵ֣ית יִשְׂרָאֵ֗ל לֹ֤א יֹאבוּ֙ לִ/שְׁמֹ֣עַ אֵלֶ֔י/ךָ כִּֽי אֵינָ֥/ם אֹבִ֖ים לִ/שְׁמֹ֣עַ אֵלָ֑/י כִּ֚י כָּל בֵּ֣ית יִשְׂרָאֵ֔ל חִזְקֵי מֵ֥צַח וּ/קְשֵׁי לֵ֖ב הֵֽמָּה", "en": {"kjv": "But the house of Israel will not hearken unto thee; for they will not hearken unto me: for all the house of Israel are impudent and hardhearted.", "web": "But the house of Israel will not listen to you; for they will not listen to me: for all the house of Israel are obstinate and hard-hearted.", "bsb": "But the house of Israel will be unwilling to listen to you, since they are unwilling to listen to Me. For the whole house of Israel is hard-headed and hard-hearted.", "asv": "But the house of Israel will not hearken unto thee; for they will not hearken unto me: for all the house of Israel are of a hard forehead and of a stiff heart.", "ylt": "but the house of Israel are not willing to hearken unto thee, for they are not willing to hearken unto Me, for all the house of Israel are brazen-faced and strong-hearted.", "dra": "But the house of Israel will not hearken to thee: because they will not hearken to me: for all the house of Israel are of a hard forehead and an obstinate heart.", "bbe": "But the children of Israel will not give ear to you; for they have no mind to give ear to me: for all the children of Israel have a hard brow and a stiff heart.", "geneva": "But the house of Israel will not obey thee: for they will not obey me: yea, all the house of Israel are impudent and stiffe hearted.", "wycliffe": "But the hous of Israel nylen here thee, for thei nylen here me. For al the hous of Israel is of vnschamefast forheed, and of hard herte.", "rotherham": "But the house of Israel will not be willing to hearken unto thee, for they are not willing to hearken unto me,—for all the house of Israel are bold of forehead and hard of heart.", "darby": "But the house of Israel will not hearken unto thee, for none of them will hearken unto me. For all the house of Israel are hard of forehead and stiff of heart.", "twenty": "", "jps": "But the house of Israel will not consent to hearken unto thee; for they consent not to hearken unto Me; for all the house of Israel are of a hard forehead and of a stiff heart.", "acv": "But the house of Israel will not hearken to thee, for they will not hearken to me. For all the house of Israel are of a hard forehead and of a stiff heart.", "anderson": "", "haweis": "", "noyes": "But the house of Israel will not hearken to thee, for they will not hearken to me. For the whole house of Israel is brazen-faced and stiff-hearted.", "webster": "But the house of Israel will not hearken to thee; for they will not hearken to me: for all the house of Israel [are] impudent and hard-hearted.", "vulgate": "domus autem Israhel nolent audire te quia nolunt audire me omnis quippe domus Israhel adtrita fronte est et duro corde;", "brenton": "But the house of Israel will not be willing to hearken to thee; for they will not hearken to me: for all the house of Israel are stubborn and hard-hearted."}}, {"v": 8, "ref": "3:8", "o": "הִנֵּ֨ה נָתַ֧תִּי אֶת פָּנֶ֛י/ךָ חֲזָקִ֖ים לְ/עֻמַּ֣ת פְּנֵי/הֶ֑ם וְ/אֶֽת מִצְחֲ/ךָ֥ חָזָ֖ק לְ/עֻמַּ֥ת מִצְחָֽ/ם", "en": {"kjv": "Behold, I have made thy face strong against their faces, and thy forehead strong against their foreheads.", "web": "Behold, I have made your face hard against their faces, and your forehead hard against their foreheads.", "bsb": "Behold, I will make your face as hard as their faces, and your forehead as hard as their foreheads.", "asv": "Behold, I have made thy face hard against their faces, and thy forehead hard against their foreheads.", "ylt": "`Lo, I have made thy face strong against their face, and thy forehead strong against their forehead.", "dra": "Behold I have made thy face stronger than their faces: and thy forehead harder than their foreheads.", "bbe": "See, I have made your face hard against their faces, and your brow hard against their brows.", "geneva": "Beholde, I haue made thy face strong against their faces, and thy forehead harde against their foreheads.", "wycliffe": "Lo! Y yaf thi face strongere than the faces of hem, and thi forheed hardere than the forheedis of hem.", "rotherham": "Lo! I have made thy face bold like as their faces, and thy forehead bold like as their forehead.", "darby": "Behold, I have made thy face hard against their faces, and thy forehead hard against their foreheads.", "twenty": "", "jps": "Behold, I have made thy face hard against their faces, and thy forehead hard against their foreheads.", "acv": "Behold, I have made thy face hard against their faces, and thy forehead hard against their foreheads.", "anderson": "", "haweis": "", "noyes": "Behold, I have made thy face strong against their faces, and thy forehead strong against their foreheads.", "webster": "Behold, I have made thy face strong against their faces, and thy forehead strong against their foreheads.", "vulgate": "ecce dedi faciem tuam valentiorem faciebus eorum et frontem tuam duriorem frontibus eorum;", "brenton": "And, behold, I have made thy face strong against their faces, and I will strengthen thy power against their power."}}, {"v": 9, "ref": "3:9", "o": "כְּ/שָׁמִ֛יר חָזָ֥ק מִ/צֹּ֖ר נָתַ֣תִּי מִצְחֶ֑/ךָ לֹֽא תִירָ֤א אוֹתָ/ם֙ וְ/לֹא תֵחַ֣ת מִ/פְּנֵי/הֶ֔ם כִּ֛י בֵּֽית מְרִ֖י הֵֽמָּה", "en": {"kjv": "As an adamant harder than flint have I made thy forehead: fear them not, neither be dismayed at their looks, though they be a rebellious house.", "web": "As an adamant harder than flint have I made your forehead: don’t be afraid of them, neither be dismayed at their looks, though they are a rebellious house.", "bsb": "I will make your forehead like a diamond, harder than flint. Do not be afraid of them or dismayed at their presence, even though they are a rebellious house.”", "asv": "As an adamant harder than flint have I made thy forehead: fear them not, neither be dismayed at their looks, though they are a rebellious house.", "ylt": "As an adamant harder than a rock I have made thy forehead; thou dost not fear them, nor art thou affrighted before them, for a rebellious house are they.'", "dra": "I have made thy face like an adamant and like flint: fear them not, neither be thou dismayed at their presence: for they are a provoking house.", "bbe": "Like a diamond harder than rock I have made your brow: have no fear of them and do not be overcome by their looks, for they are an uncontrolled people.", "geneva": "I haue made thy forehead as the adamant, and harder then the flint: feare them not therefore, neither be afraid at their lookes: for they are a rebellious house.", "wycliffe": "Y yaf thi face as an adamaunt, and as a flynt; drede thou not hem, nether drede thou of the face of hem, for it is an hous terrynge to wraththe.", "rotherham": "As an adamant harder than flint, have I made thy forehead,—thou shalt not fear them neither shalt thou be dismayed at their faces, For a perverse house, they are!", "darby": "As an adamant harder than flint have I made thy forehead. Fear them not, neither be dismayed at them, for they are a rebellious house.", "twenty": "", "jps": "As an adamant harder than flint have I made thy forehead; fear them not, neither be dismayed at their looks, for they are a rebellious house.'", "acv": "As an adamant, harder than flint, I have made thy forehead. Fear them not, nor be dismayed at their looks, though they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "As an adamant, harder than flint, have I made thy forehead; fear them not, nor be dismayed at their looks; for they are a rebellious house.", "webster": "As an adamant harder than flint have I made thy forehead: fear them not, neither be dismayed at their looks, though they [are] a rebellious house.", "vulgate": "ut adamantem et ut silicem dedi faciem tuam ne timeas eos neque metuas a facie eorum quia domus exasperans est;", "brenton": "And it shall be continually stronger than a rock: be not afraid of them, neither be dismayed at their faces, because it is a provoking house."}}, {"v": 10, "ref": "3:10", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י בֶּן אָדָ֕ם אֶת כָּל דְּבָרַ/י֙ אֲשֶׁ֣ר אֲדַבֵּ֣ר אֵלֶ֔י/ךָ קַ֥ח בִּֽ/לְבָבְ/ךָ֖ וּ/בְ/אָזְנֶ֥י/ךָ שְׁמָֽע", "en": {"kjv": "Moreover he said unto me, Son of man, all my words that I shall speak unto thee receive in thine heart, and hear with thine ears.", "web": "Moreover he said to me, Son of man, all my words that I shall speak to you receive in your heart, and hear with your ears.", "bsb": "“Son of man,” He added, “listen carefully to all the words I speak to you, and take them to heart.", "asv": "Moreover he said unto me, Son of man, all my words that I shall speak unto thee receive in thy heart, and hear with thine ears.", "ylt": "And He saith unto me, `Son of man, all My words, that I speak unto thee, receive with thy heart, and with thine ears hear;", "dra": "And he said to me: Son of man, receive in thy heart, and hear with thy ears, all the words that I speak to thee:", "bbe": "Then he said to me, Son of man, take into your heart all my words which I am about to say to you, and let your ears be open to them.", "geneva": "He said moreouer vnto me, Sonne of man, receiue in thine heart al my words that I speake vnto thee, and heare them with thine eares,", "wycliffe": "And he seide to me, Sone of man, take in thin herte, and here with thin eeris alle these my wordis, whiche Y speke to thee.", "rotherham": "Then said he unto me,— Son of man. All my words which I shall speak unto thee, receive thou into thy heart and in thine ears, hear thou:", "darby": "And he said unto me, Son of man, all my words which I shall speak unto thee, receive in thy heart, and hear with thine ears;", "twenty": "", "jps": "Moreover He said unto me: 'Son of man, all My words that I shall speak unto thee receive in thy heart, and hear with thine ears.", "acv": "Moreover he said to me, Son of man, all my words that I shall speak to thee, receive in thy heart, and hear with thine ears.", "anderson": "", "haweis": "", "noyes": "Moreover, he said to me: Son of man, all my words, which I shall speak to thee, receive in thy heart, and hear with thine ears!", "webster": "Moreover he said to me, Son of man, all my words that I shall speak to thee receive in thy heart, and hear with thy ears.", "vulgate": "et dixit ad me fili hominis omnes sermones meos quos loquor ad te adsume in corde tuo et auribus tuis audi;", "brenton": "And he said to me, Son of man, receive into thine heart all the words that I have spoken to thee, and hear them with thine ears."}}, {"v": 11, "ref": "3:11", "o": "וְ/לֵ֨ךְ בֹּ֤א אֶל הַ/גּוֹלָה֙ אֶל בְּנֵ֣י עַמֶּ֔/ךָ וְ/דִבַּרְתָּ֤ אֲלֵי/הֶם֙ וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהֹוִ֑ה אִֽם יִשְׁמְע֖וּ וְ/אִם יֶחְדָּֽלוּ", "en": {"kjv": "And go, get thee to them of the captivity, unto the children of thy people, and speak unto them, and tell them, Thus saith the Lord God; whether they will hear, or whether they will forbear.", "web": "Go to them of the captivity, to the children of your people, and speak to them, and tell them, Thus says the Lord Yahweh; whether they will hear, or whether they will forbear.", "bsb": "Go to your people, the exiles; speak to them and tell them, ‘This is what the Lord GOD says,’ whether they listen or refuse to listen.”", "asv": "And go, get thee to them of the captivity, unto the children of thy people, and speak unto them, and tell them, Thus saith the Lord Jehovah; whether they will hear, or whether they will forbear.", "ylt": "and go, enter in unto the Removed, unto the sons of thy people, and thou hast spoken unto them, and hast said unto them: Thus said the Lord Jehovah: whether they hear, or whether they forbear.'", "dra": "And go get thee in to them of the captivity, to the children of thy people, and thou shalt speak to them, and shalt say to them: Thus saith the Lord: If so be they will hear, and will forbear.", "bbe": "And go now to those who have been taken away as prisoners, to the children of your people, and say to them, This is what the Lord has said; if they give ear or if they do not.", "geneva": "And goe and enter to them that are led away captiues vnto the children of thy people, and speake vnto them, and tell them, Thus saith the Lord God: but surely they will not heare, neither will they in deede cease.", "wycliffe": "And go thou, and entre to the passyng ouer, to the sones of thi puple. And thou schalt speke to hem, and thou schalt seie to hem, The Lord God seith these thingis, if perauenture thei heren, and resten.", "rotherham": "then go get thee unto them of the captivity, unto the sons of thy people, and thou shalt speak unto them and say unto them, Thus saith My Lord Yahweh, whether they will hear or whether they will forbear.", "darby": "and go, get thee to them of the captivity, unto the children of thy people, and speak unto them, and tell them, Thus saith the Lord Jehovah, — whether they will hear or whether they will forbear.", "twenty": "", "jps": "And go, get thee to them of the captivity, unto the children of thy people, and speak unto them, and tell them: Thus saith the L-rd GOD; whether they will hear, or whether they will forbear.'", "acv": "And go, get thee to those of the captivity, to the sons of thy people, and speak to them, and tell them, Thus says the lord Jehovah, whether they will hear, or whether they will forbear.", "anderson": "", "haweis": "", "noyes": "And go, get thee to them of the captivity, to the children of thy people, and speak to them, and say to them, Thus saith the Lord Jehovah; whether they will hear, or whether they will forbear.", "webster": "And depart, go to them of the captivity, to the children of thy people, and speak to them, and tell them, Thus saith the Lord GOD; whether they will hear, or whether they will forbear.", "vulgate": "et vade ingredere ad transmigrationem ad filios populi tui et loqueris ad eos et dices eis haec dicit Dominus Deus si forte audiant et quiescant;", "brenton": "And go thy way, go in to the captivity, to the children of thy people, and thou shalt speak to them, and say to them, Thus saith the Lord; whether they will hear, or whether they will forbear."}}, {"v": 12, "ref": "3:12", "o": "וַ/תִּשָּׂאֵ֣/נִי ר֔וּחַ וָ/אֶשְׁמַ֣ע אַחֲרַ֔/י ק֖וֹל רַ֣עַשׁ גָּד֑וֹל בָּר֥וּךְ כְּבוֹד יְהוָ֖ה מִ/מְּקוֹמֽ/וֹ", "en": {"kjv": "Then the spirit took me up, and I heard behind me a voice of a great rushing, saying, Blessed be the glory of the Lord from his place.", "web": "Then the Spirit lifted me up, and I heard behind me the voice of a great rushing, saying, Blessed be Yahweh’s glory from his place.", "bsb": "Then the Spirit lifted me up, and I heard a great rumbling sound behind me: ‘Blessed be the glory of the LORD in His dwelling place!’", "asv": "Then the Spirit lifted me up, and I heard behind me the voice of a great rushing, saying, Blessed be the glory of Jehovah from his place.", "ylt": "And lift me up doth a spirit, and I hear behind me a noise, a great rushing--`Blessed is the honour of Jehovah from His place!' --", "dra": "And the spirit took me up, and I heard behind me the voice of a great commotion, saying: Blessed be the glory of the Lord, from his place.", "bbe": "Then I was lifted up by the wind, and at my back the sound of a great rushing came to my ears when the glory of the Lord was lifted up from his place.", "geneva": "Then the spirite tooke me vp, and I heard behinde me a noise of a great russhing, saying, Blessed be ye glorie of the Lord out of his place.", "wycliffe": "And the spirit took me, and Y herde after me the vois of a greet mouyng. The blessid glorie of the Lord was herd fro his place;", "rotherham": "Then the Spirit lifted me up, and I heard behind me the sound of a great rushing,— Blessed be the glory of Yahweh. From his place!", "darby": "And the Spirit lifted me up, and I heard behind me the sound of a great rushing, [saying,] Blessed be the glory of Jehovah from his place!", "twenty": "", "jps": "Then a spirit lifted me up, and I heard behind me the voice of a great rushing: 'Blessed be the glory of HaShem from His place';", "acv": "Then the Spirit lifted me up, and I heard behind me the voice of a great rushing, saying, Blessed be the glory of Jehovah from his place.", "anderson": "", "haweis": "", "noyes": "Then the spirit lifted me up, and I heard behind me the sound, as of a great rushing, saying, \"Praised be the majesty of Jehovah from his place!\"", "webster": "Then the spirit took me up, and I heard behind me a voice of a great rushing, [saying], Blessed [be] the glory of the LORD from his place.", "vulgate": "et adsumpsit me spiritus et audivi post me vocem commotionis magnae benedicta gloria Domini de loco suo;", "brenton": "Then the Spirit took me up, and I heard behind me the voice as of a great earthquake, saying, Blessed be the glory of the Lord from his place."}}, {"v": 13, "ref": "3:13", "o": "וְ/ק֣וֹל כַּנְפֵ֣י הַ/חַיּ֗וֹת מַשִּׁיקוֹת֙ אִשָּׁ֣ה אֶל אֲחוֹתָ֔/הּ וְ/ק֥וֹל הָ/אוֹפַנִּ֖ים לְ/עֻמָּתָ֑/ם וְ/ק֖וֹל רַ֥עַשׁ גָּדֽוֹל", "en": {"kjv": "I heard also the noise of the wings of the living creatures that touched one another, and the noise of the wheels over against them, and a noise of a great rushing.", "web": "I heard the noise of the wings of the living creatures as they touched one another, and the noise of the wheels beside them, even the noise of a great rushing.", "bsb": "It was the sound of the wings of the living creatures brushing against one another and the sound of the wheels beside them, a great rumbling sound.", "asv": "And I heard the noise of the wings of the living creatures as they touched one another, and the noise of the wheels beside them, even the noise of a great rushing.", "ylt": "even a noise of the wings of the living creatures touching one another, and a noise of the wheels over-against them, even a noise of a great rushing.", "dra": "The noise of the wings of the living creatures striking one against another, and the noise of the wheels following the living creatures, and the noise of a great commotion.", "bbe": "And there was the sound of the wings of the living beings touching one another, and the sound of the wheels at their side, the sound of a great rushing.", "geneva": "I heard also the noyse of the wings of the beasts, that touched one another, and the ratling of the wheeles that were by them, euen a noyse of a great russhing.", "wycliffe": "and Y herde the vois of wyngis of the beestis smytynge oon an othir, and the vois of wheelis suynge the beestis, and the vois of greet stiryng.", "rotherham": "Yea the sound of the wings of the living ones, gently touching each other, and the sound of the wheels, along with them, even the sound of a great rushing.", "darby": "— and the sound of the wings of the living creatures that touched one another, and the sound of the wheels beside them, and the sound of a great rushing.", "twenty": "", "jps": "also the noise of the wings of the living creatures as they touched one another, and the noise of the wheels beside them, even the noise of a great rushing.", "acv": "And I heard the noise of the wings of the living creatures as they touched each other, and the noise of the wheels beside them, even the noise of a great rushing.", "anderson": "", "haweis": "", "noyes": "I heard also the noise of the wings of the living creatures, that touched one another, and the noise of the wheels beside them, even a noise of a great rushing.", "webster": "[I heard] also the noise of the wings of the living creatures that touched one another, and the noise of the wheels over against them, and the noise of a great rushing.", "vulgate": "et vocem alarum animalium percutientium alteram ad alteram et vocem rotarum sequentium animalia et vocem commotionis magnae;", "brenton": "And I perceived the sound of the wings of the living creatures clapping one to the other, and the sound of the wheels was near them, and the sound of the earthquake."}}, {"v": 14, "ref": "3:14", "o": "וְ/ר֥וּחַ נְשָׂאַ֖תְ/נִי וַ/תִּקָּחֵ֑/נִי וָ/אֵלֵ֥ךְ מַר֙ בַּ/חֲמַ֣ת רוּחִ֔/י וְ/יַד יְהוָ֥ה עָלַ֖/י חָזָֽקָה", "en": {"kjv": "So the spirit lifted me up, and took me away, and I went in bitterness, in the heat of my spirit; but the hand of the Lord was strong upon me.", "web": "So the Spirit lifted me up, and took me away; and I went in bitterness, in the heat of my spirit; and the hand of Yahweh was strong on me.", "bsb": "So the Spirit lifted me up and took me away, and I went in bitterness and in the anger of my spirit, with the strong hand of the LORD upon me.", "asv": "So the Spirit lifted me up, and took me away; and I went in bitterness, in the heat of my spirit; and the hand of Jehovah was strong upon me.", "ylt": "And a spirit hath lifted me up, and doth take me away, and I go bitterly, in the heat of my spirit, and the hand of Jehovah on me is strong.", "dra": "The spirit also lifted me, and took me up: and I went away in bitterness in the indignation of my spirit: for the hand of the Lord was with me, strengthening me.", "bbe": "And the wind, lifting me up, took me away: and I went in the heat of my spirit, and the hand of the Lord was strong on me.", "geneva": "So the spirit lift me vp, and tooke me away and I went in bitternesse, and indignation of my spirite, but the hand of the Lord was strong vpon me.", "wycliffe": "Also the spirit reiside me, and took me. And Y yede forth bittir in the indignacioun of my spirit; for the hond of the Lord was with me, and coumfortide me.", "rotherham": "So the Spirit lifted me up, and took me away,—and I went bitterly, in the rage of my spirit, but the hand of Yahweh upon me was strong.", "darby": "And the Spirit lifted me up, and took me away; and I went in bitterness, in the heat of my spirit, and the hand of Jehovah was strong upon me.", "twenty": "", "jps": "So a spirit lifted me up, and took me away; and I went in bitterness, in the heat of my spirit, and the hand of HaShem was strong upon me.", "acv": "So the Spirit lifted me up, and took me away. And I went in bitterness, in the heat of my spirit, and the hand of Jehovah was strong upon me.", "anderson": "", "haweis": "", "noyes": "So the spirit lifted me up, and took me away, and I went in bitterness, in the heat of my spirit; but the hand of Jehovah was strong upon me.", "webster": "So the spirit lifted me up, and took me away, and I went in bitterness, in the heat of my spirit; but the hand of the LORD was strong upon me.", "vulgate": "spiritus quoque levavit me et adsumpsit me et abii amarus in indignatione spiritus mei manus enim Domini erat mecum confortans me;", "brenton": "And the Spirit lifted me, and took me up, and I went in the impulse of my spirit; and the hand of the Lord was mighty upon me."}}, {"v": 15, "ref": "3:15", "o": "וָ/אָב֨וֹא אֶל הַ/גּוֹלָ֜ה תֵּ֣ל אָ֠בִיב הַ/יֹּשְׁבִ֤ים אֶֽל נְהַר כְּבָר֙ ו/אשר וָֽ/אֵשֵׁ֔ב הֵ֖מָּה יוֹשְׁבִ֣ים שָׁ֑ם וָ/אֵשֵׁ֥ב שָׁ֛ם שִׁבְעַ֥ת יָמִ֖ים מַשְׁמִ֥ים בְּ/תוֹכָֽ/ם", "en": {"kjv": "Then I came to them of the captivity at Tel–abib, that dwelt by the river of Chebar, and I sat where they sat, and remained there astonished among them seven days.", "web": "Then I came to them of the captivity at Tel Aviv, that lived by the river Chebar, and to where they lived; and I sat there overwhelmed among them seven days.", "bsb": "I came to the exiles at Tel-abib who dwelt by the River Kebar. And for seven days I sat where they sat and remained there among them, overwhelmed.", "asv": "Then I came to them of the captivity at Tel-abib, that dwelt by the river Chebar, and to where they dwelt; and I sat there overwhelmed among them seven days.", "ylt": "And I come in unto the Removed, at Tel-Ahib, who are dwelling at the river Chebar, and where they are dwelling I also dwell seven days, causing astonishment in their midst.", "dra": "And I came to them of the captivity, to the heap of new corn, to them that dwelt by the river Chobar, and I sat where they sat: and I remained there seven days mourning in the midst of them.", "bbe": "Then I came to those who had been taken away as prisoners, who were at Telabib by the river Chebar, and I was seated among them full of wonder for seven days.", "geneva": "Then I came to them that were led away captiues to Tel-abib, that dwelt by the riuer Chebar, and I sate where they sate, and remained there astonished among them seuen dayes.", "wycliffe": "And Y cam to the passyng ouer, to the heep of newe fruytis, to hem that dwelliden bisidis the flood Chobar. And Y sat where thei saten, and Y dwellide there seuene daies, weilynge, in the myddis of hem.", "rotherham": "Thus came I unto them of the captivity, at Tel-abib. who were dwelling towards he river Chebar and I dwelt where They were dwelling; yea I dwelt there seven days, stunned in their midst,", "darby": "And I came to them of the captivity at Tel-abib, that dwelt by the river Chebar, and I sat where they sat; and I sat there astonied among them seven days.", "twenty": "", "jps": "Then I came to them of the captivity at Tel-abib, that dwelt by the river Chebar, and I sat where they sat; and I remained there appalled among them seven days.", "acv": "Then I came to those of the captivity at Tel-abib, who dwelt by the river Chebar, and to where they dwelt. And I sat there overwhelmed among them seven days.", "anderson": "", "haweis": "", "noyes": "Then I came to them of the captivity at Tel-abib, that dwelt by the river Chebar; and I dwelt where they dwelt; I even dwelt astonished among them seven days.", "webster": "Then I came to them of the captivity at Tel-abib, that dwelt by the river of Kebar, and I sat where they sat, and remained there astonished among them seven days.", "vulgate": "et veni ad transmigrationem acervum novarum frugum ad eos qui habitabant iuxta flumen Chobar et sedi ubi illi sedebant et mansi ibi septem diebus maerens in medio eorum;", "brenton": "Then I passed through the air and came into the captivity, and went round to them that dwelt by the river of Chobar who were there; and I sat there seven days, conversant in the midst of them."}}, {"v": 16, "ref": "3:16", "o": "וַ/יְהִ֕י מִ/קְצֵ֖ה שִׁבְעַ֣ת יָמִ֑ים וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass at the end of seven days, that the word of the Lord came unto me, saying,", "web": "At the end of seven days, Yahweh’s word came to me, saying,", "bsb": "At the end of seven days the word of the LORD came to me, saying,", "asv": "And it came to pass at the end of seven days, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, at the end of seven days,", "dra": "And at the end of seven days the word of the Lord came to me, saying:", "bbe": "And at the end of seven days, the word of the Lord came to me, saying,", "geneva": "And at the ende of seuen dayes, the worde of the Lord came againe vnto me, saying,", "wycliffe": "Forsothe whanne seuene daies weren passid, the word of the Lord was maad to me, and seide, Sone of man,", "rotherham": "And it came to pass at the end of seven days, that the word of Yahweh came unto me saying", "darby": "And it came to pass at the end of seven days, that the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass at the end of seven days, that the word of HaShem came unto me, saying:", "acv": "And it came to pass at the end of seven days, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And at the end of seven days, the word of Jehovah came to me, and said:", "webster": "And it came to pass at the end of seven days, that the word of the LORD came to me, saying,", "vulgate": "cum autem pertransissent septem dies factum est verbum Domini ad me dicens;", "brenton": "And after the seven days the word of the Lord came to me, saying, Son of man,"}}, {"v": 17, "ref": "3:17", "o": "בֶּן אָדָ֕ם צֹפֶ֥ה נְתַתִּ֖י/ךָ לְ/בֵ֣ית יִשְׂרָאֵ֑ל וְ/שָׁמַעְתָּ֤ מִ/פִּ/י֙ דָּבָ֔ר וְ/הִזְהַרְתָּ֥ אוֹתָ֖/ם מִמֶּֽ/נִּי", "en": {"kjv": "Son of man, I have made thee a watchman unto the house of Israel: therefore hear the word at my mouth, and give them warning from me.", "web": "Son of man, I have made you a watchman to the house of Israel: therefore hear the word from my mouth, and give them warning from me.", "bsb": "“Son of man, I have made you a watchman for the house of Israel. Whenever you hear a word from My mouth, give them a warning from Me.", "asv": "Son of man, I have made thee a watchman unto the house of Israel: therefore hear the word at my mouth, and give them warning from me.", "ylt": "that there is a word of Jehovah unto me, saying, `Son of man, a watchman I have given thee to the house of Israel, and thou hast heard from My mouth a word, and hast warned them from Me.", "dra": "Son of man, I have made thee a watchman to the house of Israel: and thou shalt hear the word out of my mouth, and shalt tell it them from me.", "bbe": "Son of man, I have made you a watchman for the children of Israel: so give ear to the word of my mouth, and give them word from me of their danger.", "geneva": "Sonne of man, I haue made thee a watchman vnto the house of Israel: therefore heare the worde at my mouth, and giue them warning from me.", "wycliffe": "Y yaf thee `a spiere to the hous of Israel. And thou schalt here of my mouth a word, and thou schalt telle to hem of me.", "rotherham": "Son of man, A watchman, have I appointed thee to the house of Israel,—and thou shalt hear, at my mouth a message, and shalt warn them from me.", "darby": "Son of man, I have appointed thee a watchman unto the house of Israel, and thou shalt hear the word from my mouth, and give them warning from me.", "twenty": "", "jps": "'Son of man, I have appointed thee a watchman unto the house of Israel; and when thou shalt hear a word at My mouth, thou shalt give them warning from Me.", "acv": "Son of man, I have made thee a watchman to the house of Israel. Therefore hear the word at my mouth, and give them warning from me.", "anderson": "", "haweis": "", "noyes": "Son of man, I have set thee as a watchman to the house of Israel; therefore hear the word from my mouth, and warn them from me!", "webster": "Son of man, I have made thee a watchman to the house of Israel: therefore hear the word at my mouth, and give them warning from me.", "vulgate": "fili hominis speculatorem dedi te domui Israhel et audies de ore meo verbum et adnuntiabis eis ex me;", "brenton": "I have made thee a watchman to the house of Israel; and thou shalt hear a word of my mouth, and shalt threaten them from me."}}, {"v": 18, "ref": "3:18", "o": "בְּ/אָמְרִ֤/י לָֽ/רָשָׁע֙ מ֣וֹת תָּמ֔וּת וְ/לֹ֣א הִזְהַרְתּ֗/וֹ וְ/לֹ֥א דִבַּ֛רְתָּ לְ/הַזְהִ֥יר רָשָׁ֛ע מִ/דַּרְכּ֥/וֹ הָ/רְשָׁעָ֖ה לְ/חַיֹּת֑/וֹ ה֤וּא רָשָׁע֙ בַּ/עֲוֺנ֣/וֹ יָמ֔וּת וְ/דָמ֖/וֹ מִ/יָּדְ/ךָ֥ אֲבַקֵּֽשׁ", "en": {"kjv": "When I say unto the wicked, Thou shalt surely die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, to save his life; the same wicked man shall die in his iniquity; but his blood will I require at thine hand.", "web": "When I tell the wicked, You shall surely die; and you give him no warning, nor speak to warn the wicked from his wicked way, to save his life; the same wicked man shall die in his iniquity; but his blood will I require at your hand.", "bsb": "If I say to the wicked man, ‘You will surely die,’ but you do not warn him or speak out to warn him from his wicked way to save his life, that wicked man will die in his iniquity, and I will hold you responsible for his blood.", "asv": "When I say unto the wicked, Thou shalt surely die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, to save his life; the same wicked man shall die in his iniquity; but his blood will I require at thy hand.", "ylt": "In My saying to the wicked: Thou dost surely die; and thou hast not warned him, nor hast spoken to warn the wicked from his wicked way, so that he doth live; he--the wicked--in his iniquity dieth, and his blood from thy hand I require.", "dra": "If, when I say to the wicked, Thou shalt surely die: thou declare it not to him, nor speak to him, that he may be converted from his wicked way, and live: the same wicked man shall die in his iniquity, but I will require his blood at thy hand.", "bbe": "When I say to the evil-doer, Death will certainly be your fate; and you give him no word of it and say nothing to make clear to the evil-doer the danger of his evil way, so that he may be safe; that same evil man will come to death in his evil-doing; but I will make you responsible for his blood.", "geneva": "When I shall say vnto the wicked, Thou shalt surely die, and thou giuest not him warning, nor speakest to admonish the wicked of his wicked way, that he may liue, the same wicked man shall die in his iniquitie: but his blood will I require at thine hande.", "wycliffe": "If whanne Y seie to the wickid man, Thou schalt die bi deth, thou tellist not to hym, and spekist not to hym, that he be turned fro his wickid weie, and lyue; thilke wickid man schal die in his wickidnesse, but Y schal seke his blood of thin hond.", "rotherham": "When I say to the lawless man— Thou shalt surely die, and thou hast not given him warning, neither hast spoken to warn the lawless man from his lawless way, to save himself alive the same lawless man in his iniquity shall die, but his blood, at thy hand, will I require.", "darby": "When I say unto the wicked, Thou shalt certainly die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, that he may live: the same wicked [man] shall die in his iniquity; but his blood will I require at thy hand.", "twenty": "", "jps": "When I say unto the wicked: Thou shalt surely die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, to save his life; the same wicked man shall die in his iniquity, but his blood will I require at thy hand.", "acv": "When I say to a wicked man, Thou shall surely die, and thou give him no warning, nor speak to warn the wicked man from his wicked way, to save his life, the same wicked man shall die in his iniquity, but I will require his blood at thy hand.", "anderson": "", "haweis": "", "noyes": "When I say to the wicked, Thou shalt surely die! and thou givest him not warning, nor speakest to warn the wicked from his wicked way, so that he may live, that wicked man shall die for his iniquity; but his blood will I require at thy hand.", "webster": "When I say to the wicked, Thou shalt surely die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, to save his life; the same wicked [man] shall die in his iniquity; but his blood will I require at thy hand.", "vulgate": "si dicente me ad impium morte morieris non adnuntiaveris ei neque locutus fueris ut avertatur a via sua impia et vivat ipse impius in iniquitate sua morietur sanguinem autem eius de manu tua requiram;", "brenton": "When I say to the wicked, Thou shalt surely die; and thou hast not warned him, to give warning to the wicked, to turn from his ways, that he should live; that wicked man shall die in his iniquity; but his blood will I require at thy hand."}}, {"v": 19, "ref": "3:19", "o": "וְ/אַתָּה֙ כִּֽי הִזְהַ֣רְתָּ רָשָׁ֔ע וְ/לֹא שָׁב֙ מֵֽ/רִשְׁע֔/וֹ וּ/מִ/דַּרְכּ֖/וֹ הָ/רְשָׁעָ֑ה ה֚וּא בַּ/עֲוֺנ֣/וֹ יָמ֔וּת וְ/אַתָּ֖ה אֶֽת נַפְשְׁ/ךָ֥ הִצַּֽלְתָּ", "en": {"kjv": "Yet if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.", "web": "Yet if you warn the wicked, and he doesn’t turn from his wickedness, nor from his wicked way, he shall die in his iniquity; but you have delivered your soul.", "bsb": "But if you warn a wicked man and he does not turn from his wickedness and his wicked way, he will die in his iniquity, but you will have saved yourself.", "asv": "Yet if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.", "ylt": "And thou, because thou hast warned the wicked, and he hath not turned back from his wickedness, and from his wicked way, he in his iniquity dieth, and thou thy soul hast delivered.", "dra": "But if thou give warning to the wicked, and he be not converted from his wickedness, and from his evil way: he indeed shall die in his iniquity, but thou hast delivered thy soul.", "bbe": "But if you give the evil-doer word of his danger, and he is not turned from his sin or from his evil way, death will overtake him in his evil-doing; but your life will be safe.", "geneva": "Yet if thou warne the wicked, and he turne not from his wickednesse, nor from his wicked way, he shall die in his iniquitie, but thou hast deliuered thy soule.", "wycliffe": "Forsothe if thou tellist to the wickid man, and he is not conuertid fro his wickidnesse, and fro his wickid weie; sotheli he schal die in his wickidnesse, but thou hast delyuerid thi soule.", "rotherham": "Whereas when thou hast warned a lawless man, and he hath not turned from his lawlessness and from his lawless way he in his iniquity shall die, but Thou hast delivered thine own soul.", "darby": "But if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.", "twenty": "", "jps": "Yet if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.", "acv": "Yet if thou warn the wicked man, and he does not turn from his wickedness, nor from his wicked way, he shall die in his iniquity, but thou have delivered thy soul.", "anderson": "", "haweis": "", "noyes": "Yet if thou warn the wicked, and he turn not from his wickedness, and from his wicked way, he shall die for his iniquity, but thou hast delivered thy soul.", "webster": "Yet if thou shalt warn the wicked, and he shall not turn from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.", "vulgate": "si autem tu adnuntiaveris impio et ille non fuerit conversus ab impietate sua et via sua impia ipse quidem in iniquitate sua morietur tu autem animam tuam liberasti;", "brenton": "But if thou warn the wicked, and he turn not from his wickedness, and from his way, that wicked man shall die in his iniquity, and thou shalt deliver thy soul."}}, {"v": 20, "ref": "3:20", "o": "וּ/בְ/שׁ֨וּב צַדִּ֤יק מִ/צִּדְק/וֹ֙ וְ/עָ֣שָׂה עָ֔וֶל וְ/נָתַתִּ֥י מִכְשׁ֛וֹל לְ/פָנָ֖י/ו ה֣וּא יָמ֑וּת כִּ֣י לֹ֤א הִזְהַרְתּ/וֹ֙ בְּ/חַטָּאת֣/וֹ יָמ֔וּת וְ/לֹ֣א תִזָּכַ֗רְןָ צִדְקֹתָ/ו֙ אֲשֶׁ֣ר עָשָׂ֔ה וְ/דָמ֖/וֹ מִ/יָּדְ/ךָ֥ אֲבַקֵּֽשׁ", "en": {"kjv": "Again, When a righteous man doth turn from his righteousness, and commit iniquity, and I lay a stumblingblock before him, he shall die: because thou hast not given him warning, he shall die in his sin, and his righteousness which he hath done shall not be remembered; but his blood will I require at thine hand.", "web": "Again, when a righteous man does turn from his righteousness, and commit iniquity, and I lay a stumbling block before him, he shall die: because you have not given him warning, he shall die in his sin, and his righteous deeds which he has done shall not be remembered; but his blood will I require at your hand.", "bsb": "Now if a righteous man turns from his righteousness and commits iniquity, and I put a stumbling block before him, he will die. If you did not warn him, he will die in his sin, and the righteous acts he did will not be remembered. And I will hold you responsible for his blood.", "asv": "Again, when a righteous man doth turn from his righteousness, and commit iniquity, and I lay a stumblingblock before him, he shall die: because thou hast not given him warning, he shall die in his sin, and his righteous deeds which he hath done shall not be remembered; but his blood will I require at thy hand.", "ylt": "`And in the turning back of the righteous from his righteousness, and he hath done perversity, and I have put a stumbling-block before him, he dieth; because thou hast not warned him, in his sin he dieth, and not remembered is his righteousness that he hath done, and his blood from thy hand I require.", "dra": "Moreover if the just man shall turn away from his justice, and shall commit iniquity: I will lay a stumblingblock before him, he shall die, because thou hast not given him warning: he shall die in his sin, and his justices which he hath done, shall not be remembered: but I will require his blood at thy hand.", "bbe": "Again, when an upright man, turning away from his righteousness, does evil, and I put a cause of falling in his way, death will overtake him: because you have given him no word of his danger, death will overtake him in his evil-doing, and there will be no memory of the upright acts which he has done; but I will make you responsible for his blood.", "geneva": "Likewise if a righteous man turne from his righteousnesse, and commit iniquitie, I will lay a stumbling blocke before him, and he shall die, because thou hast not giuen him warning: he shall die in his sinne, and his righteous deedes, which he hath done, shall not be remembred: but his blood will I require at thine hand.", "wycliffe": "But also if a iust man is turned fro his riytfulnesse, and doith wickidnesse, Y schal sette an hirtyng bifor hym; he schal die, for thou teldist not to hym; he schal die in his synne, and hise riytfulnessis, whiche he dide, schulen not be in mynde, but Y schal seke his blood of thin hond.", "rotherham": "And when a righteous man hath turned from his righteousness, and committed perversity, and I have suffered a stumbling- block to be laid before him he shall die,—though thou hast not warned him, in his sin, shall he die, neither shall be remembered his righteous deeds which he hath done, but his blood, at thy hand will I require;", "darby": "And when a righteous [man] doth turn from his righteousness, and do what is wrong, and I lay a stumbling-block before him, he shall die; because thou hast not given him warning, he shall die in his sin, and his righteous acts which he hath done shall not be remembered; but his blood will I require at thy hand.", "twenty": "", "jps": "Again, when a righteous man doth turn from his righteousness, and commit iniquity, I will lay a stumblingblock before him, he shall die; because thou hast not given him warning, he shall die in his sin, and his righteous deeds which he hath done shall not be remembered; but his blood will I require at thy hand.", "acv": "Again, when a righteous man turns from his righteousness, and commits iniquity, and I lay a stumbling block before him, he shall die. Because thou have not given him warning, he shall die in his sin, and his righteous deeds which he has done shall not be remembered, but I will require his blood at thy hand.", "anderson": "", "haweis": "", "noyes": "Again, when a righteous man turneth from his righteousness, and committeth iniquity, and I lay a stumbling-block before him, and he shall die because thou hast not given him warning, he will die for his sin; and his righteousness which he hath done will not be remembered; but his blood will I require at thy hand.", "webster": "Again, When a righteous [man] doth turn from his righteousness, and commit iniquity, and I lay a stumbling-block before him, he shall die: because thou hast not given him warning, he shall die in his sin, and his righteousness which he hath done shall not be remembered; but his blood will I require at thy hand.", "vulgate": "sed et si conversus iustus a iustitia sua fecerit iniquitatem ponam offendiculum coram eo ipse morietur quia non adnuntiasti ei in peccato suo morietur et non erunt in memoria iustitiae eius quas fecit sanguinem vero eius de manu tua requiram;", "brenton": "And when the righteous turns away from his righteousness, and commits a trespass, and I shall bring punishment before him, he shall die, because thou didst not warn him: he shall even die in his sins, because his righteousness shall not be remembered; but his blood will I require at thine hand."}}, {"v": 21, "ref": "3:21", "o": "וְ/אַתָּ֞ה כִּ֧י הִזְהַרְתּ֣/וֹ צַדִּ֗יק לְ/בִלְתִּ֥י חֲטֹ֛א צַדִּ֖יק וְ/ה֣וּא לֹא חָטָ֑א חָי֤וֹ יִֽחְיֶה֙ כִּ֣י נִזְהָ֔ר וְ/אַתָּ֖ה אֶֽת נַפְשְׁ/ךָ֥ הִצַּֽלְתָּ", "en": {"kjv": "Nevertheless if thou warn the righteous man, that the righteous sin not, and he doth not sin, he shall surely live, because he is warned; also thou hast delivered thy soul.", "web": "Nevertheless if you warn the righteous man, that the righteous not sin, and he does not sin, he shall surely live, because he took warning; and you have delivered your soul.", "bsb": "But if you warn the righteous man not to sin, and he does not sin, he will indeed live because he heeded your warning, and you will have saved yourself.”", "asv": "Nevertheless if thou warn the righteous man, that the righteous sin not, and he doth not sin, he shall surely live, because he took warning; and thou hast delivered thy soul.", "ylt": "And thou, because thou hast warned him--the righteous--that the righteous sin not, and he hath not sinned, he surely liveth, because he hath been warned; and thou thy soul hast delivered.'", "dra": "But if thou warn the just man, that the just may not sin, and he doth not sin: living he shall live, because thou hast warned him, and thou hast delivered thy soul.", "bbe": "But if you say to the upright man that he is not to do evil, he will certainly keep his life because he took note of your word; and your life will be safe.", "geneva": "Neuerthelesse, if thou admonish that righteous man, that the righteous sinne not, and that he doeth not sinne, he shall liue because he is admonished: also thou hast deliuered thy soule.", "wycliffe": "Forsothe if thou tellist to a iust man, that a iust man do not synne, and he doith not synne, he lyuynge schal lyue, for thou teldist to hym, and thou hast delyuered thi soule.", "rotherham": "whereas when Thou hast warned a righteous man. That a righteous man must not sin and he hath not sinned, he shall surely live in that he took warning, and thou hast delivered thine own soul.", "darby": "And if thou warn the righteous [man], that the righteous sin not, and he doth not sin, he shall certainly live, for he hath taken warning; and thou hast delivered thy soul.", "twenty": "", "jps": "Nevertheless if thou warn the righteous man, that the righteous sin not, and he doth not sin, he shall surely live, because he took warning; and thou hast delivered thy soul.'", "acv": "Nevertheless if thou warn the righteous man, that the righteous man not sin, and he does not sin, he shall surely live, because he took warning, and thou have delivered thy soul.", "anderson": "", "haweis": "", "noyes": "Yet if thou warn the righteous man, that he sin not, and the righteous man doth not sin, he shall surely live, because he hath received warning; and thou hast delivered thy soul.", "webster": "Nevertheless if thou shalt warn the righteous [man], that the righteous sin not, and he doth not sin, he shall surely live, because he is warned; also thou hast delivered thy soul.", "vulgate": "si autem tu adnuntiaveris iusto ut non peccet iustus et ille non peccaverit vivens vivet quia adnuntiasti ei et tu animam tuam liberasti;", "brenton": "But if thou warn the righteous not to sin, and he sin not, the righteous shall surely live, because thou hast warned him; and thou shalt deliver thine own soul."}}, {"v": 22, "ref": "3:22", "o": "וַ/תְּהִ֥י עָלַ֛/י שָׁ֖ם יַד יְהוָ֑ה וַ/יֹּ֣אמֶר אֵלַ֗/י ק֥וּם צֵא֙ אֶל הַ/בִּקְעָ֔ה וְ/שָׁ֖ם אֲדַבֵּ֥ר אוֹתָֽ/ךְ", "en": {"kjv": "And the hand of the Lord was there upon me; and he said unto me, Arise, go forth into the plain, and I will there talk with thee.", "web": "The hand of Yahweh was there on me; and he said to me, Arise, go out into the plain, and I will there talk with you.", "bsb": "And there the hand of the LORD was upon me, and He said to me, “Get up, go out to the plain, and there I will speak with you.”", "asv": "And the hand of Jehovah was there upon me; and he said unto me, Arise, go forth into the plain, and I will there talk with thee.", "ylt": "And there is on me there a hand of Jehovah, and He saith to me, `Rise, go forth to the valley, and there I do speak with thee.'", "dra": "And the hand of the Lord was upon me, and he said to me: Rise and go forth into the plain, and there I will speak to thee.", "bbe": "And the hand of the Lord was on me there; and he said, Get up and go out into the valley and there I will have talk with you.", "geneva": "And the hande of the Lord was there vpon me, and he said vnto me, Arise, and goe into the fielde, and I will there talke with thee.", "wycliffe": "And the hond of the Lord was maad on me, and he seide to me, Rise thou, and go out in to the feeld, and there Y schal speke with thee.", "rotherham": "Then came upon me there the hand of Yahweh,—and he said unto me, Arise go forth into the valley, and there, will I speak with thee.", "darby": "And the hand of Jehovah was there upon me; and he said unto me, Arise, go forth into the valley, and there I will talk with thee.", "twenty": "", "jps": "And the hand of HaShem came there upon me; and He said unto me: 'Arise, go forth into the plain, and I will there speak with thee.'", "acv": "And the hand of Jehovah was there upon me, and he said to me, Arise, go forth into the plain, and I will talk with thee there.", "anderson": "", "haweis": "", "noyes": "And the hand of Jehovah was there upon me, and he said to me, Arise, go forth into the plain, and there will I speak with thee.", "webster": "And the hand of the LORD was there upon me; and he said to me, Arise, go forth into the plain, and I will there talk with thee.", "vulgate": "et facta est super me manus Domini et dixit ad me surgens egredere in campum et ibi loquar tecum;", "brenton": "And the hand of the Lord came upon me; and he said to me, Arise, and go forth into the plain, and there shalt thou be spoken to."}}, {"v": 23, "ref": "3:23", "o": "וָ/אָקוּם֮ וָ/אֵצֵ֣א אֶל הַ/בִּקְעָה֒ וְ/הִנֵּה שָׁ֤ם כְּבוֹד יְהוָה֙ עֹמֵ֔ד כַּ/כָּב֕וֹד אֲשֶׁ֥ר רָאִ֖יתִי עַל נְהַר כְּבָ֑ר וָ/אֶפֹּ֖ל עַל פָּנָֽ/י", "en": {"kjv": "Then I arose, and went forth into the plain: and, behold, the glory of the Lord stood there, as the glory which I saw by the river of Chebar: and I fell on my face.", "web": "Then I arose, and went out into the plain: and behold, Yahweh’s glory stood there, as the glory which I saw by the river Chebar; and I fell on my face.", "bsb": "So I got up and went out to the plain, and behold, the glory of the LORD was present there, like the glory I had seen by the River Kebar, and I fell facedown.", "asv": "Then I arose, and went forth into the plain: and, behold, the glory of Jehovah stood there, as the glory which I saw by the river Chebar; and I fell on my face.", "ylt": "And I rise and go forth unto the valley, and lo, there the honour of Jehovah is standing as the honour that I had seen by the river Chebar, and I fall on my face.", "dra": "And I rose up, and went forth into the plain: and behold the glory of the Lord stood there, like the glory which I saw by the river Chobar: and I fell upon my face.", "bbe": "Then I got up and went out into the valley; and I saw the glory of the Lord resting there as I had seen it by the river Chebar; and I went down on my face.", "geneva": "So when I had risen vp, and gone foorth into the fielde, beholde, the glorie of the Lord stoode there, as the glorie which I sawe by the riuer Chebar, and I fell downe vpon my face.", "wycliffe": "And Y roos, and yede out in to the feeld. And lo! the glorie of the Lord stood there, as the glorie which Y siy bisidis the flood Chobar; and Y felle doun on my face.", "rotherham": "So I arose and went forth into the valley, and lo! there the glory of Yahweh, standing, like the glory which I saw by the river Chebar,-and I fell upon my face.", "darby": "And I arose, and went forth into the valley, and behold, the glory of Jehovah stood there, like the glory which I saw by the river Chebar; and I fell on my face.", "twenty": "", "jps": "Then I arose, and went forth into the plain; and, behold, the glory of HaShem stood there, as the glory which I saw by the river Chebar; and I fell on my face.", "acv": "Then I arose, and went forth into the plain. And, behold, the glory of Jehovah stood there, as the glory which I saw by the river Chebar, and I fell on my face.", "anderson": "", "haweis": "", "noyes": "Then I arose, and went forth into the plain, and lo, the glory of Jehovah stood there, as the glory which I saw by the river Chebar; and I fell upon my face.", "webster": "Then I arose, and went forth into the plain; and behold, the glory of the LORD stood there, as the glory which I saw by the river of Kebar: and I fell on my face.", "vulgate": "et surgens egressus sum in campum et ecce ibi gloria Domini stabat quasi gloria quam vidi iuxta fluvium Chobar et cecidi in faciem meam;", "brenton": "And I arose, and went forth to the plain: and, behold, the glory of the Lord stood there, according to the vision, and according to the glory of the Lord, which I saw by the river of Chobar: and I fell on my face."}}, {"v": 24, "ref": "3:24", "o": "וַ/תָּבֹא בִ֣/י ר֔וּחַ וַ/תַּעֲמִדֵ֖/נִי עַל רַגְלָ֑/י וַ/יְדַבֵּ֤ר אֹתִ/י֙ וַ/יֹּ֣אמֶר אֵלַ֔/י בֹּ֥א הִסָּגֵ֖ר בְּ/ת֥וֹךְ בֵּיתֶֽ/ךָ", "en": {"kjv": "Then the spirit entered into me, and set me upon my feet, and spake with me, and said unto me, Go, shut thyself within thine house.", "web": "Then the Spirit entered into me, and set me on my feet; and he spoke with me, and said to me, Go, shut yourself inside your house.", "bsb": "Then the Spirit entered me and set me on my feet. He spoke with me and said, “Go, shut yourself inside your house.", "asv": "Then the Spirit entered into me, and set me upon my feet; and he spake with me, and said unto me, Go, shut thyself within thy house.", "ylt": "And come into me doth a spirit, and causeth me to stand on my feet, and He speaketh with me, and saith unto me, `Go in, be shut up in the midst of thy house.", "dra": "And the spirit entered into me, and set me upon my feet: and he spoke to me, and said to me: Go in; and shut thyself up in the midst of thy house.", "bbe": "Then the spirit came into me and put me on my feet; and he had talk with me and said to me, Go and keep yourself shut up inside your house.", "geneva": "Then the Spirit entred into me, which set me vp vpon my feete, and spake vnto me, and said to me, Come, and shut thy selfe within thine house.", "wycliffe": "And the spirit entride in to me, and settide me on my feet. And he spak to me, and seide to me, Entre thou, and be thou closid in the myddis of thin hous.", "rotherham": "Then the Spirit entered into me, and caused me to stand upon my feet,—and he spake with me and said unto me, Go in shut thyself up, in the midst of thine own house,", "darby": "And the Spirit entered into me, and set me upon my feet; and he spoke with me, and said unto me, Go, shut thyself within thy house.", "twenty": "", "jps": "Then spirit entered into me, and set me upon my feet; and He spoke with me, and said unto me: 'Go, shut thyself within thy house.", "acv": "Then the Spirit entered into me, and set me upon my feet. And he spoke with me, and said to me, Go, shut thyself within thy house.", "anderson": "", "haweis": "", "noyes": "Then the spirit entered into me, and set me upon my feet. And he spake with me, and said to me: Go, shut thyself within thy house.", "webster": "Then the spirit entered into me, and set me upon my feet, and spoke with me, and said to me, Go, shut thyself within thy house.", "vulgate": "et ingressus est in me spiritus et statuit me super pedes meos et locutus est mihi et dixit ad me ingredere et includere in medio domus tuae;", "brenton": "Then the Spirit came upon me, and set me on my feet, and spoke to me, and said to me, Go in, and shut thyself up in the midst of thine house."}}, {"v": 25, "ref": "3:25", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם הִנֵּ֨ה נָתְנ֤וּ עָלֶ֨י/ךָ֙ עֲבוֹתִ֔ים וַ/אֲסָר֖וּ/ךָ בָּ/הֶ֑ם וְ/לֹ֥א תֵצֵ֖א בְּ/תוֹכָֽ/ם", "en": {"kjv": "But thou, O son of man, behold, they shall put bands upon thee, and shall bind thee with them, and thou shalt not go out among them:", "web": "But you, son of man, behold, they shall lay bands on you, and shall bind you with them, and you shall not go out among them:", "bsb": "And you, son of man, they will tie with ropes, and you will be bound so that you cannot go out among the people.", "asv": "But thou, son of man, behold, they shall lay bands upon thee, and shall bind thee with them, and thou shalt not go out among them:", "ylt": "`And thou, son of man, lo, they have put on thee thick bands, and have bound thee with them, and thou goest not forth in their midst;", "dra": "And thou, O son of man, behold they shall put bands upon thee, and they shall bind thee with them: and thou shalt not go forth from the midst of them.", "bbe": "But see, O son of man, I will put bands on you, prisoning you in them, and you will not go out among them:", "geneva": "But thou, O sonne of man, beholde, they shall put bandes vpon thee, and shall binde thee with them, and thou shalt not goe out among them.", "wycliffe": "And thou, sone of man, lo! boondis ben youun on thee, and thei schulen bynde thee with tho, and thou schalt not go out in the myddis of hem.", "rotherham": "And thou—O son of man, lo! they have put upon thee bands, and they will bind thee therewith,-.so that thou go not forth in their midst;", "darby": "And thou, son of man, behold, they shall put bands upon thee, and shall bind thee therewith, and thou shalt not go out among them.", "twenty": "", "jps": "But thou, son of man, behold, bands shall be put upon thee, and thou shalt be bound with them, and thou shalt not go out among them;", "acv": "But thou, son of man, behold, they shall lay bands upon thee, and shall bind thee with them, and thou shall not escape from them.", "anderson": "", "haweis": "", "noyes": "And behold, O son of man, bands shall be put upon thee, and thou shalt be bound therewith; and thou shalt not go out among them.", "webster": "But thou, O son of man, behold, they shall put bands upon thee, and shall bind thee with them, and thou shalt not go out among them:", "vulgate": "et tu fili hominis ecce data sunt super te vincula et ligabunt te in eis et non egredieris in medio eorum;", "brenton": "And thou, son of man, behold, bonds are prepared for thee, and they shall bind thee with them, and thou shalt not come forth of the midst of them."}}, {"v": 26, "ref": "3:26", "o": "וּ/לְשֽׁוֹנְ/ךָ֙ אַדְבִּ֣יק אֶל חִכֶּ֔/ךָ וְ/נֶֽאֱלַ֔מְתָּ וְ/לֹא תִֽהְיֶ֥ה לָ/הֶ֖ם לְ/אִ֣ישׁ מוֹכִ֑יחַ כִּ֛י בֵּ֥ית מְרִ֖י הֵֽמָּה", "en": {"kjv": "And I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover: for they are a rebellious house.", "web": "and I will make your tongue stick to the roof of your mouth, that you shall be mute, and shall not be to them a reprover; for they are a rebellious house.", "bsb": "I will make your tongue stick to the roof of your mouth, and you will be silent and unable to rebuke them, though they are a rebellious house.", "asv": "and I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover; for they are a rebellious house.", "ylt": "and thy tongue I cause to cleave unto thy palate, and thou hast been dumb, and art not to them for a reprover, for a rebellious house are they.", "dra": "And I will make thy tongue stick fast to the roof of thy mouth, and thou shalt be dumb, and not as a man that reproveth: because they are a provoking house.", "bbe": "And I will make your tongue fixed to the roof of your mouth, so that you have no voice and may not make protests to them: for they are an uncontrolled people.", "geneva": "And I will make thy tongue cleaue to the roofe of thy mouth, that thou shalt be dume, and shalt not be to them as a man that rebuketh: for they are a rebellious house.", "wycliffe": "And Y schal make thi tunge to cleue to the roof of thi mouth, and thou schalt be doumbe, and thou schalt not be as a man rebuykinge; for it is an hous terrynge to wraththe.", "rotherham": "thy tongue also, will I cause to cleave unto the roof of thy mouth, so shalt thou be dumb and not be to them a reprover,— For a perverse house, they are!", "darby": "And I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover; for they are a rebellious house.", "twenty": "", "jps": "and I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover; for they are a rebellious house.", "acv": "And I will make thy tongue cling to the roof of thy mouth, that thou shall be mute, and shall not be a reprover to them, for they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "And I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover; for they are a rebellious house.", "webster": "And I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover: for they [are] a rebellious house.", "vulgate": "et linguam tuam adherescere faciam palato tuo et eris mutus nec quasi vir obiurgans quia domus exasperans est;", "brenton": "Also I will bind thy tongue, and thou shalt be dumb, and shalt not be to them a reprover: because it is a provoking house."}}, {"v": 27, "ref": "3:27", "o": "וּֽ/בְ/דַבְּרִ֤/י אֽוֹתְ/ךָ֙ אֶפְתַּ֣ח אֶת פִּ֔י/ךָ וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהֹוִ֑ה הַ/שֹּׁמֵ֤עַ יִשְׁמָע֙ וְ/הֶ/חָדֵ֣ל יֶחְדָּ֔ל כִּ֛י בֵּ֥ית מְרִ֖י הֵֽמָּה", "en": {"kjv": "But when I speak with thee, I will open thy mouth, and thou shalt say unto them, Thus saith the Lord God; He that heareth, let him hear; and he that forbeareth, let him forbear: for they are a rebellious house.", "web": "But when I speak with you, I will open your mouth, and you shall tell them, Thus says the Lord Yahweh: He who hears, let him hear; and he who forbears, let him forbear: for they are a rebellious house.", "bsb": "But when I speak with you, I will open your mouth, and you are to tell them, ‘This is what the Lord GOD says.’ Whoever listens, let him listen; and whoever refuses, let him refuse, for they are a rebellious house.", "asv": "But when I speak with thee, I will open thy mouth, and thou shalt say unto them, Thus saith the Lord Jehovah: He that heareth, let him hear; and he that forbeareth, let him forbear: for they are a rebellious house.", "ylt": "And in My speaking with thee, I do open thy mouth, and thou hast said unto them: Thus said the Lord Jehovah; the hearer doth hear, and the forbearer doth forbear; for a rebellious house are they.", "dra": "But when I shall speak to thee, I will open thy mouth, and thou shalt say to them: Thus saith the Lord God: He that heareth, let him hear: and he that forbeareth, let him forbear: for they are a provoking house.", "bbe": "But when I have talk with you I will make your mouth open, and you are to say to them, This is what the Lord has said: Let the hearer give ear; and as for him who will not, let him keep his ears shut: for they are an uncontrolled people.", "geneva": "But when I shall haue spoken vnto thee, I will open thy mouth, and thou shalt say vnto them, Thus saith the Lord God, He that heareth, let him heare, and he that leaueth off, let him leaue: for they are a rebellious house.", "wycliffe": "But whanne Y schal speke to thee, Y schal opene thi mouth, and thou schalt seie to hem, The Lord God seith these thingis, He that herith, here, and he that restith, reste; for it is an hous terrynge to wraththe.", "rotherham": "But when I speak with thee, I will open thy mouth, and thou shalt say unto them. Thus saith My Lord Yahweh,—He that is minded to hear, let him hear, And he that is minded to forbear, let him forbear! For a perverse house, they are!", "darby": "And when I speak with thee, I will open thy mouth, and thou shalt say unto them, Thus saith the Lord Jehovah: He that heareth, let him hear; and he that forbeareth, let him forbear: for they are a rebellious house.", "twenty": "", "jps": "But when I speak with thee, I will open thy mouth, and thou shalt say unto them: Thus saith the L-rd GOD; he that heareth, let him hear, and he that forbeareth, let him forbear; for they are a rebellious house.", "acv": "But when I speak with thee, I will open thy mouth, and thou shall say to them, Thus says the lord Jehovah. He who hears, let him hear, and he who forbears, let him forbear, for they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "But when I speak with thee, I will open thy mouth, and thou shalt say to them, Thus saith the Lord Jehovah: He that will hear, let him hear, and he that will forbear, let him forbear; for they are a rebellious house.", "webster": "But when I speak with thee, I will open thy mouth, and thou shalt say to them, Thus saith the Lord GOD; He that heareth, let him hear; and he that forbeareth, let him forbear: for they [are] a rebellious house.", "vulgate": "cum autem locutus fuero tibi aperiam os tuum et dices ad eos haec dicit Dominus Deus qui audit audiat et qui quiescit quiescat quia domus exasperans est;", "brenton": "But when I speak to thee, I will open thy mouth, and thou shalt say to them, Thus saith the Lord, He that hears, let him hear; and he that is disobedient, let him be disobedient: because it is a provoking house."}}]}, {"c": 4, "verses": [{"v": 1, "ref": "4:1", "o": "וְ/אַתָּ֤ה בֶן אָדָם֙ קַח לְ/ךָ֣ לְבֵנָ֔ה וְ/נָתַתָּ֥ה אוֹתָ֖/הּ לְ/פָנֶ֑י/ךָ וְ/חַקּוֹתָ֥ עָלֶ֛י/הָ עִ֖יר אֶת יְרוּשָׁלִָֽם", "en": {"kjv": "Thou also, son of man, take thee a tile, and lay it before thee, and pourtray upon it the city, even Jerusalem:", "web": "You also, son of man, take a tile, and lay it before yourself, and portray on it a city, even Jerusalem:", "bsb": "“Now you, son of man, take a brick, place it before you, and draw on it the city of Jerusalem.", "asv": "Thou also, son of man, take thee a tile, and lay it before thee, and portray upon it a city, even Jerusalem:", "ylt": "`And thou, son of man, take to thee a brick, and thou hast put it before thee, and hast graven on it a city--Jerusalem,", "dra": "And thou, O son of man, take thee a tile, and lay it before thee: and draw upon it the plan of the city of Jerusalem.", "bbe": "And you, son of man, take a back and put it before you and on it make a picture of a town, even Jerusalem.", "geneva": "Thou also sonne of man, take thee a bricke, and lay it before thee, and pourtray vpon it the citie, euen Ierusalem,", "wycliffe": "And thou, sone of man, take to thee a tijl stoon; and thou schalt sette it bifore thee, and thou schalt discriue ther ynne the citee of Jerusalem.", "rotherham": "Thou therefore O son of man Take thee a tile, and lay it before thee,—and portray thereon a city, even Jerusalem.", "darby": "And thou, son of man, take thee a brick, and lay it before thee, and portray upon it a city, — Jerusalem:", "twenty": "", "jps": "Thou also, son of man, take thee a tile, and lay it before thee, and trace upon it a city, even Jerusalem;", "acv": "Thou also, son of man, take thee a tile, and lay it before thee, and portray upon it a city, even Jerusalem.", "anderson": "", "haweis": "", "noyes": "And thou, son of man, take thee a tile, and lay it before thee, and portray upon it a city, even Jerusalem.", "webster": "Thou also, son of man, take thee a tile, and lay it before thee, and pourtray upon it the city, [even] Jerusalem;", "vulgate": "et tu fili hominis sume tibi laterem et pones eum coram te et describes in eo civitatem Hierusalem;", "brenton": "And thou, son of man, take thee a brick, and thou shalt set it before thy face, and shalt portray on it the city, even Jerusalem."}}, {"v": 2, "ref": "4:2", "o": "וְ/נָתַתָּ֨ה עָלֶ֜י/הָ מָצ֗וֹר וּ/בָנִ֤יתָ עָלֶ֨י/הָ֙ דָּיֵ֔ק וְ/שָׁפַכְתָּ֥ עָלֶ֖י/הָ סֹֽלְלָ֑ה וְ/נָתַתָּ֨ה עָלֶ֧י/הָ מַחֲנ֛וֹת וְ/שִׂים עָלֶ֥י/הָ כָּרִ֖ים סָבִֽיב", "en": {"kjv": "And lay siege against it, and build a fort against it, and cast a mount against it; set the camp also against it, and set battering rams against it round about.", "web": "and lay siege against it, and build forts against it, and cast up a mound against it; set camps also against it, and plant battering rams against it all around.", "bsb": "Then lay siege against it: Construct a siege wall, build a ramp to it, set up camps against it, and place battering rams around it on all sides.", "asv": "and lay siege against it, and build forts against it, and cast up a mound against it; set camps also against it, and plant battering rams against it round about.", "ylt": "and hast placed against it a siege, and builded against it a fortification, and poured out against it a mount, and placed against it camps, yea, set thou against it battering-rams round about.", "dra": "And lay siege against it, and build forts, and cast up a mount, and set a camp against it, and place battering rams round about it.", "bbe": "And make an attack on it, shutting it in, building strong places against it, and making high an earthwork against it; and put up tents against it, placing engines all round it for smashing down its walls.", "geneva": "And lay siege against it, and builde a fort against it, and cast a mount against it: set the campe also against it, and lay engins of warre against it rounde about.", "wycliffe": "And thou schalt ordeyne bisegyng ayenus that Jerusalem; and thou schalt bilde strengthis, and thou schalt bere togidere erthe, and thou shalt yyue oostis of batel ayens it, and thou schalt sette engynes in cumpas.", "rotherham": "Then shalt thou lay siege against it And build up against it a siege-wall And cast up against it, a mound,— And set against it camps, And place against it battering-rams, round about.", "darby": "and lay siege against it, and build forts against it, and cast a mound against it, and set camps against it, and place battering-rams against it round about.", "twenty": "", "jps": "and lay siege against it, and build forts against it, and cast up a mound against it; set camps also against it, and set battering rams against it round about.", "acv": "And lay siege against it, and build forts against it, and cast up a mound against it. Also set camps against it, and plant battering rams against it round about.", "anderson": "", "haweis": "", "noyes": "And lay siege against it, and build a tower against it, and cast up a mound against it; set a camp also against it, and place battering-rams against it round about.", "webster": "And lay siege against it, and build a fort against it, and cast a mount against it; set the camp also against it, and set [battering] rams against it on every side.", "vulgate": "et ordinabis adversus eam obsidionem et aedificabis munitiones et conportabis aggerem et dabis contra eam castra et pones arietes in gyro;", "brenton": "And thou shalt besiege it, and build works against it, and throw up a mound round about it, and pitch camps against it, and set up engines round about."}}, {"v": 3, "ref": "4:3", "o": "וְ/אַתָּ֤ה קַח לְ/ךָ֙ מַחֲבַ֣ת בַּרְזֶ֔ל וְ/נָתַתָּ֤ה אוֹתָ/הּ֙ קִ֣יר בַּרְזֶ֔ל בֵּינְ/ךָ֖ וּ/בֵ֣ין הָ/עִ֑יר וַ/הֲכִינֹתָה֩ אֶת פָּנֶ֨י/ךָ אֵלֶ֜י/הָ וְ/הָיְתָ֤ה בַ/מָּצוֹר֙ וְ/צַרְתָּ֣ עָלֶ֔י/הָ א֥וֹת הִ֖יא לְ/בֵ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Moreover take thou unto thee an iron pan, and set it for a wall of iron between thee and the city: and set thy face against it, and it shall be besieged, and thou shalt lay siege against it. This shall be a sign to the house of Israel.", "web": "Take for yourself an iron pan, and set it for a wall of iron between you and the city: and set your face toward it, and it shall be besieged, and you shall lay siege against it. This shall be a sign to the house of Israel.", "bsb": "Then take an iron plate and set it up as an iron wall between yourself and the city. Turn your face toward it so that it is under siege, and besiege it. This will be a sign to the house of Israel.", "asv": "And take thou unto thee an iron pan, and set it for a wall of iron between thee and the city: and set thy face toward it, and it shall be besieged, and thou shalt lay siege against it. This shall be a sign to the house of Israel.", "ylt": "And thou, take to thee an iron pan, and thou hast made it a wall of iron between thee and the city; and thou hast prepared thy face against it, and it hath been in a siege, yea, thou hast laid siege against it. A sign it is to the house of Israel.", "dra": "And take unto thee an iron pan, and set it for a wall of iron between thee and the city: and set thy face resolutely against it, and it shall be besieged, and thou shalt lay siege against it: it is a sign to the house of Israel.", "bbe": "And take a flat iron plate, and put it for a wall of iron between you and the town: and let your face be turned to it, and it will be shut in and you will make an attack on it. This will be a sign to the children of Israel.", "geneva": "Moreouer, take an yron pan, and set it for a wall of yron betweene thee and the citie, and direct thy face towarde it, and it shall be besieged, and thou shalt lay siege against it: this shall be a signe vnto the house of Israel.", "wycliffe": "And take thou to thee an irone friynge panne; and thou schalt sette it in to an irone wal bitwixe thee and bitwixe the cite; and thou schalt sette stidfastli thi face to it, and it schal be in to bisegyng, and thou schalt cumpasse it; it is a signe to the hous of Israel.", "rotherham": "Thou, therefore take thee a pan of iron, and set it for a wall of iron, between thee and the city,—then shalt thou direct thy face against it and it shall come into siege and thou shalt lay siege to it, a sign, shall it be to the house of Israel.", "darby": "And take thou unto thee an iron plate, and put it [for] a wall of iron between thee and the city; and set thy face against it, and it shall be besieged, and thou shalt lay siege against it: this shall be a sign to the house of Israel.", "twenty": "", "jps": "And take thou unto thee an iron griddle, and set it for a wall of iron between thee and the city; and set thy face toward it, and it shall be besieged, and thou shalt lay siege against it. This shall be a sign to the house of Israel.", "acv": "And take thou to thee an iron pan, and set it for a wall of iron between thee and the city. And set thy face toward it, and it shall be besieged, and thou shall lay siege against it. This shall be a sign to the house of Israel.", "anderson": "", "haweis": "", "noyes": "Moreover, take thou an iron pan, and set it for a wall of iron between thee and the city; and set thy face against it, that it may be besieged; and lay siege against it. This shall be a sign to the house of Israel.", "webster": "Moreover take thou to thee an iron pan, and set it [for] a wall of iron between thee and the city: and set thy face against it, and it shall be besieged, and thou shalt lay siege against it. This [shall be] a sign to the house of Israel.", "vulgate": "et tu sume tibi sartaginem ferream et pones eam murum ferreum inter te et inter civitatem et obfirmabis faciem tuam ad eam et erit in obsidionem et circumdabis eam signum est domui Israhel;", "brenton": "And take thou to thyself an iron pan, and thou shalt set it for an iron wall between thee and the city: and thou shalt set thy face against it, and it shall be in a siege, and thou shalt besiege it. This is a sign to the children of Israel."}}, {"v": 4, "ref": "4:4", "o": "וְ/אַתָּ֤ה שְׁכַב֙ עַל צִדְּ/ךָ֣ הַ/שְּׂמָאלִ֔י וְ/שַׂמְתָּ֛ אֶת עֲוֺ֥ן בֵּֽית יִשְׂרָאֵ֖ל עָלָ֑י/ו מִסְפַּ֤ר הַ/יָּמִים֙ אֲשֶׁ֣ר תִּשְׁכַּ֣ב עָלָ֔י/ו תִּשָּׂ֖א אֶת עֲוֺנָֽ/ם", "en": {"kjv": "Lie thou also upon thy left side, and lay the iniquity of the house of Israel upon it: according to the number of the days that thou shalt lie upon it thou shalt bear their iniquity.", "web": "Moreover lie on your left side, and lay the iniquity of the house of Israel on it; according to the number of the days that you shall lie on it, you shall bear their iniquity.", "bsb": "Then lie down on your left side and place the iniquity of the house of Israel upon yourself. You are to bear their iniquity for the number of days you lie on your side.", "asv": "Moreover lie thou upon thy left side, and lay the iniquity of the house of Israel upon it; according to the number of the days that thou shalt lie upon it, thou shalt bear their iniquity.", "ylt": "`And thou, lie on thy left side, and thou hast placed the iniquity of the house of Israel on it; the number of the days that thou liest on it, thou bearest their iniquity.", "dra": "And thou shalt sleep upon thy left side, and shalt lay the iniquities of the house of Israel upon it, according to the number of the days that thou shalt sleep upon it, and thou shalt take upon thee their iniquity.", "bbe": "Then, stretching yourself out on your left side, take the sin of the children of Israel on yourself: for as long as you are stretched out, so long will the sin of the children of Israel be on you.", "geneva": "Sleepe thou also vpon thy left side, and lay the iniquitie of the house of Israel vpon it: according to the nomber of the dayes, that thou shalt sleepe vpon it, thou shalt beare their iniquity.", "wycliffe": "And thou schalt slepe on thi left side, and thou schalt putte the wickidnessis of the hous of Israel on that side, in the noumbre of daies in which thou shalt slepe on that side, and thou schalt take the wickidnesse of hem.", "rotherham": "Thou, therefore lie thou on thy left side, and lay the iniquity of the house of Israel upon it,— during the number of the days which thou shalt lie thereon, shalt thou bear their punishment.", "darby": "And thou, lie upon thy left side, and lay the iniquity of the house of Israel upon it: the number of the days that thou liest upon it, thou shalt bear their iniquity.", "twenty": "", "jps": "Moreover lie thou upon thy left side, and lay the iniquity of the house of Israel upon it; according to the number of the days that thou shalt lie upon it, thou shalt bear their iniquity.", "acv": "Moreover lie thou upon thy left side, and lay the iniquity of the house of Israel upon it. According to the number of the days that thou shall lie upon it, thou shall bear their iniquity.", "anderson": "", "haweis": "", "noyes": "Lie thou also upon thy left side, and lay the iniquity of the house of Israel upon it. According to the number of days that thou shalt lie upon it, thou shalt bear their iniquity.", "webster": "Lie thou also upon thy left side, and lay the iniquity of the house of Israel upon it: [according] to the number of the days that thou shalt lie upon it thou shalt bear their iniquity.", "vulgate": "et tu dormies super latus tuum sinistrum et pones iniquitates domus Israhel super eo numero dierum quibus dormies super illud et adsumes iniquitatem eorum;", "brenton": "And thou shalt lie upon thy left side, and lay the iniquities of the house of Israel upon it, according to the number of the hundred and fifty days during which thou shalt lie upon it: and thou shalt bear their iniquities."}}, {"v": 5, "ref": "4:5", "o": "וַ/אֲנִ֗י נָתַ֤תִּֽי לְ/ךָ֙ אֶת שְׁנֵ֣י עֲוֺנָ֔/ם לְ/מִסְפַּ֣ר יָמִ֔ים שְׁלֹשׁ מֵא֥וֹת וְ/תִשְׁעִ֖ים י֑וֹם וְ/נָשָׂ֖אתָ עֲוֺ֥ן בֵּֽית יִשְׂרָאֵֽל", "en": {"kjv": "For I have laid upon thee the years of their iniquity, according to the number of the days, three hundred and ninety days: so shalt thou bear the iniquity of the house of Israel.", "web": "For I have appointed the years of their iniquity to be to you a number of days, even three hundred ninety days: so you shall bear the iniquity of the house of Israel.", "bsb": "For I have assigned to you 390 days, according to the number of years of their iniquity. So you shall bear the iniquity of the house of Israel.", "asv": "For I have appointed the years of their iniquity to be unto thee a number of days, even three hundred and ninety days: so shalt thou bear the iniquity of the house of Israel.", "ylt": "And I--I have laid on thee the years of their iniquity, the number of days, three hundred and ninety days; and thou hast borne the iniquity of the house of Israel.", "dra": "And I have laid upon thee the years of their iniquity, according to the number of the days three hundred and ninety days: and thou shalt bear the iniquity of the house of Israel.", "bbe": "For I have had the years of their sin measured for you by a number of days, even three hundred and ninety days: and you will take on yourself the sin of the children of Israel.", "geneva": "For I haue layed vpon thee the yeeres of their iniquitie, according to the nomber of the dayes, euen three hundreth and ninetie dayes: so shalt thou beare the iniquitie of the house of Israel.", "wycliffe": "Forsothe Y yaf to thee the yeeris of the wickidnesse of hem bi noumbre of daies, thre hundrid and nynti daies; and thou schalt bere the wickidnesse of the hous of Israel.", "rotherham": "I therefore have appointed thee the years of their punishment, by the number of days a hundred and ninety days,—so shalt thou bear the iniquity of the house of Israel.", "darby": "And I have appointed thee the years of their iniquity, according to the number of the days, three hundred and ninety days; and thou shalt bear the iniquity of the house of Israel.", "twenty": "", "jps": "For I have appointed the years of their iniquity to be unto thee a number of days, even three hundred and ninety days; so shalt thou bear the iniquity of the house of Israel.", "acv": "For I have appointed the years of their iniquity to be a number of days to thee, even three hundred and ninety days. So thou shall bear the iniquity of the house of Israel.", "anderson": "", "haweis": "", "noyes": "But for the years of their iniquity I appoint thee days, three hundred and ninety days; so long shalt thou bear the iniquity of the house of Israel.", "webster": "For I have laid upon thee the years of their iniquity, according to the number of the days, three hundred and ninety days: so shalt thou bear the iniquity of the house of Israel.", "vulgate": "ego autem dedi tibi annos iniquitatis eorum numero dierum trecentos et nonaginta dies et portabis iniquitatem domus Israhel;", "brenton": "For I have appointed thee their iniquities for a number of days, for a hundred and ninety days: so thou shalt bear the iniquities of the house of Israel."}}, {"v": 6, "ref": "4:6", "o": "וְ/כִלִּיתָ֣ אֶת אֵ֗לֶּה וְ/שָׁ֨כַבְתָּ֜ עַל צִדְּ/ךָ֤ ה/ימיני הַ/יְמָנִי֙ שֵׁנִ֔ית וְ/נָשָׂ֖אתָ אֶת עֲוֺ֣ן בֵּית יְהוּדָ֑ה אַרְבָּעִ֣ים י֔וֹם י֧וֹם לַ/שָּׁנָ֛ה י֥וֹם לַ/שָּׁנָ֖ה נְתַתִּ֥י/ו לָֽ/ךְ", "en": {"kjv": "And when thou hast accomplished them, lie again on thy right side, and thou shalt bear the iniquity of the house of Judah forty days: I have appointed thee each day for a year.", "web": "Again, when you have accomplished these, you shall lie on your right side, and shall bear the iniquity of the house of Judah: forty days, each day for a year, have I appointed it to you.", "bsb": "When you have completed these days, lie down again, but on your right side, and bear the iniquity of the house of Judah. I have assigned to you 40 days, a day for each year.", "asv": "And again, when thou hast accomplished these, thou shalt lie on thy right side, and shalt bear the iniquity of the house of Judah: forty days, each day for a year, have I appointed it unto thee.", "ylt": "And thou hast completed these, and hast lain on thy right side, a second time, and hast borne the iniquity of the house of Judah forty days--a day for a year--a day for a year I have appointed to thee.", "dra": "And when thou hast accomplished this, thou shalt sleep again upon thy right side, and thou shalt take upon thee the iniquity of the house of Juda forty days: a day for a year, yea, a day for a year I have appointed to thee.", "bbe": "And when these days are ended, turning on your right side, you are to take on yourself the sin of the children of Judah: forty days, a day for a year, I have had it fixed for you.", "geneva": "And when thou hast accomplished them, sleepe againe vpon thy right side, and thou shalt beare the iniquitie of the house of Iudah fourtie dayes: I haue appointed thee a day for a yeere, euen a day for a yeere.", "wycliffe": "And whanne thou hast fillid these thingis, thou schalt slepe the secounde tyme on thi riytside. And thou schalt take the wickidnesse of the hous of Juda bi fourti daies; Y yaf to thee a dai for a yeer, a dai sotheli for a yeer.", "rotherham": "And when thou hast ended these, then shalt thou lie, on thy right side. a second time, and shalt bear the iniquity of the house of Judah,— forty days, one day for each year, have I appointed thee.", "darby": "And when thou hast accomplished them, thou shalt lie again on thy right side, and thou shalt bear the iniquity of the house of Judah forty days: I have appointed thee each day for a year.", "twenty": "", "jps": "And again, when thou hast accomplished these, thou shalt lie on thy right side, and shalt bear the iniquity of the house of Judah; forty days, each day for a year, have I appointed it unto thee.", "acv": "And again, when thou have accomplished these, thou shall lie on thy right side, and shall bear the iniquity of the house of Judah forty days, each day for a year. I have appointed it to thee.", "anderson": "", "haweis": "", "noyes": "And when thou hast brought them to an end, then lie upon thy right side, and bear the iniquity of the house of Judah forty days. I have appointed thee a day for a year.", "webster": "And when thou hast accomplished them, lie again on thy right side, and thou shalt bear the iniquity of the house of Judah forty days: I have appointed thee each day for a year.", "vulgate": "et cum conpleveris haec dormies super latus tuum dextrum secundo et adsumes iniquitatem domus Iuda quadraginta diebus diem pro anno diem inquam pro anno dedi tibi;", "brenton": "And thou shalt accomplish this, and then shalt lie on thy right side, and shalt bear the iniquities of the house of Juda forty days: I have appointed thee a day for a year."}}, {"v": 7, "ref": "4:7", "o": "וְ/אֶל מְצ֤וֹר יְרוּשָׁלִַ֨ם֙ תָּכִ֣ין פָּנֶ֔י/ךָ וּֽ/זְרֹעֲ/ךָ֖ חֲשׂוּפָ֑ה וְ/נִבֵּאתָ֖ עָלֶֽי/הָ", "en": {"kjv": "Therefore thou shalt set thy face toward the siege of Jerusalem, and thine arm shall be uncovered, and thou shalt prophesy against it.", "web": "You shall set your face toward the siege of Jerusalem, with your arm uncovered; and you shall prophesy against it.", "bsb": "You must turn your face toward the siege of Jerusalem with your arm bared, and prophesy against it.", "asv": "And thou shalt set thy face toward the siege of Jerusalem, with thine arm uncovered; and thou shalt prophesy against it.", "ylt": "`And unto the siege of Jerusalem thou dost prepare thy face, and thine arm is uncovered, and thou hast prophesied concerning it.", "dra": "And thou shalt turn thy face to the siege of Jerusalem and thy arm shall be stretched out: and thou shalt prophesy against it.", "bbe": "And let your face be turned to where Jerusalem is shut in, with your arm uncovered, and be a prophet against it.", "geneva": "Therefore thou shalt direct thy face towarde the siege of Ierusalem, and thine arme shalbe vncouered, and thou shalt prophesie against it.", "wycliffe": "And thou schalt turne thi face to the biseging of Jerusalem; and thin arm schal be stretchid forth, and thou schalt profesie ayens it.", "rotherham": "Thus then unto the siege of Jerusalem, shalt thou direct thy face, with thine arm made bare,—so shalt thou prophesy against it.", "darby": "And thou shalt set thy face toward the siege of Jerusalem, and thine arm shall be uncovered, and thou shalt prophesy against it.", "twenty": "", "jps": "And thou shalt set thy face toward the siege of Jerusalem, with thine arm uncovered; and thou shalt prophesy against it.", "acv": "And thou shall set thy face toward the siege of Jerusalem, with thine arm uncovered, and thou shall prophesy against it.", "anderson": "", "haweis": "", "noyes": "And set thy face against besieged Jerusalem, and uncover thine arm, and prophesy against it!", "webster": "Therefore thou shalt set thy face towards the siege of Jerusalem, and thy arm [shall be] uncovered, and thou shalt prophesy against it.", "vulgate": "et ad obsidionem Hierusalem convertes faciem tuam et brachium tuum erit exertum et prophetabis adversus eam;", "brenton": "So thou shalt set thy face to the siege of Jerusalem, and shalt strengthen thine arm, and shalt prophesy against it."}}, {"v": 8, "ref": "4:8", "o": "וְ/הִנֵּ֛ה נָתַ֥תִּי עָלֶ֖י/ךָ עֲבוֹתִ֑ים וְ/לֹֽא תֵהָפֵ֤ךְ מִֽ/צִּדְּ/ךָ֙ אֶל צִדֶּ֔/ךָ עַד כַּלּוֹתְ/ךָ֖ יְמֵ֥י מְצוּרֶֽ/ךָ", "en": {"kjv": "And, behold, I will lay bands upon thee, and thou shalt not turn thee from one side to another, till thou hast ended the days of thy siege.", "web": "Behold, I lay bands on you, and you shall not turn you from one side to the other, until you have accomplished the days of your siege.", "bsb": "Now behold, I will tie you up with ropes so you cannot turn from side to side until you have finished the days of your siege.", "asv": "And, behold, I lay bands upon thee, and thou shalt not turn thee from one side to the other, till thou hast accomplished the days of thy siege.", "ylt": "And lo, I have put on thee thick bands, and thou dost not turn from side to side till thy completing the days of thy siege.", "dra": "Behold I have encompassed thee with bands: and thou shalt not turn thyself from one side to the other, till thou hast ended the days of thy siege.", "bbe": "And see, I will put bands on you; and you will be stretched out without turning from one side to the other till the days of your attack are ended.", "geneva": "And beholde, I will lay bands vpon thee, and thou shalt not turne thee from one side to another, till thou hast ended the dayes of thy siege.", "wycliffe": "Lo! Y haue cumpassid thee with boondis, and thou schalt not turne thee fro thi side in `to other side, tille thou fille the daies of thi bisegyng.", "rotherham": "And lo! I have laid upon thee-bands,—and thou shalt not turn thee from thy one side to thine other, until thou have ended the days of thy siege.", "darby": "And behold, I lay bands upon thee, and thou shalt not turn thyself from one side to the other, till thou hast ended the days of thy siege.", "twenty": "", "jps": "And, behold, I lay bands upon thee, and thou shalt not turn thee from one side to another, till thou hast accomplished the days of thy siege.", "acv": "And, behold, I lay bands upon thee, and thou shall not turn thee from one side to the other, till thou have accomplished the days of thy siege.", "anderson": "", "haweis": "", "noyes": "And behold, I will lay bands upon thee, and thou shalt not turn thee from one side to another till thou hast ended the days of thy siege.", "webster": "And behold, I will lay bands upon thee, and thou shalt not turn thee from one side to another, till thou hast ended the days of thy siege.", "vulgate": "ecce circumdedi te vinculis et non te convertes a latere tuo in latus aliud donec conpleas dies obsidionis tuae;", "brenton": "And, behold, I have prepared bonds for thee, land thou mayest not turn from thy one side to the other, until the days of thy siege shall be accomplished."}}, {"v": 9, "ref": "4:9", "o": "וְ/אַתָּ֣ה קַח לְ/ךָ֡ חִטִּ֡ין וּ֠/שְׂעֹרִים וּ/פ֨וֹל וַ/עֲדָשִׁ֜ים וְ/דֹ֣חַן וְ/כֻסְּמִ֗ים וְ/נָתַתָּ֤ה אוֹתָ/ם֙ בִּ/כְלִ֣י אֶחָ֔ד וְ/עָשִׂ֧יתָ אוֹתָ֛/ם לְ/ךָ֖ לְ/לָ֑חֶם מִסְפַּ֨ר הַ/יָּמִ֜ים אֲשֶׁר אַתָּ֣ה שׁוֹכֵ֣ב עַֽל צִדְּ/ךָ֗ שְׁלֹשׁ מֵא֧וֹת וְ/תִשְׁעִ֛ים י֖וֹם תֹּאכֲלֶֽ/נּוּ", "en": {"kjv": "Take thou also unto thee wheat, and barley, and beans, and lentiles, and millet, and fitches, and put them in one vessel, and make thee bread thereof, according to the number of the days that thou shalt lie upon thy side, three hundred and ninety days shalt thou eat thereof.", "web": "Take for yourself also wheat, and barley, and beans, and lentils, and millet, and spelt, and put them in one vessel, and make bread of it; according to the number of the days that you shall lie on your side, even three hundred ninety days, you shall eat of it.", "bsb": "But take wheat, barley, beans, lentils, millet, and spelt; put them in a single container and make them into bread for yourself. This is what you are to eat during the 390 days you lie on your side.", "asv": "Take thou also unto thee wheat, and barley, and beans, and lentils, and millet, and spelt, and put them in one vessel, and make thee bread thereof; according to the number of the days that thou shalt lie upon thy side, even three hundred and ninety days, shalt thou eat thereof.", "ylt": "`And thou, take to thee wheat, and barley, and beans, and lentiles, and millet, and spelt, and thou hast put them in one vessel, and made them to thee for bread; the number of the days that thou art lying on thy side--three hundred and ninety days--thou dost eat it.", "dra": "And take to thee wheat and barley, and beans, and lentils, and millet, and fitches, and put them in one vessel, and make thee bread thereof according to the number of the days that thou shalt lie upon thy side: three hundred and ninety days shalt thou eat thereof.", "bbe": "And take for yourself wheat and barley and different sorts of grain, and put them in one vessel and make bread for yourself from them; all the days when you are stretched on your side it will be your food.", "geneva": "Thou shalt take also vnto thee wheate, and barley, and beanes, and lentiles, and millet, and fitches, and put them in one vessell, and make thee bread thereof according to the nomber of the dayes, that thou shalt sleepe vpon thy side: euen three hundreth and ninetie dayes shalt thou eate thereof.", "wycliffe": "And take thou to thee wheete, and barli, and beenys, and tillis, and mylie, and vetchis; and thou schalt putte tho in to o vesselle. And thou schalt make to thee looues for the noumbre of daies, bi whiche thou schalt slepe on thi side; bi three hundrid and nynti daies thou schalt ete it.", "rotherham": "Thou, therefore, take thee wheat and barley and peas and lentils and millet and spelt, and put them in one vessel, and make them ready for thee as bread,—during the number of days which thou art lying on thy side. a hundred and ninety days, shalt thou eat it;", "darby": "And thou, take unto thee wheat, and barley, and beans, and lentils, and millet, and spelt, and put them in one vessel, and make thee bread thereof, [according to] the number of the days that thou liest upon thy side: three hundred and ninety days shalt thou eat thereof.", "twenty": "", "jps": "Take thou also unto thee wheat, and barley, and beans, and lentils, and millet, and spelt, and put them in one vessel, and make thee bread thereof; according to the number of the days that thou shalt lie upon thy side, even three hundred and ninety days, shalt thou eat thereof.", "acv": "Also take thou to thee wheat, and barley, and beans, and lentils, and millet, and spelt, and put them in one vessel, and make thee bread of it, according to the number of the days that thou shall lie upon thy side, even three hundred and ninety days, thou shall eat of it.", "anderson": "", "haweis": "", "noyes": "Take thou also wheat, and barley, and beans, and lentiles, and millet, and spelt, and put them into one vessel, and make thereof thy bread for the number of days that thou shalt lie upon thy side; three hundred and ninety days shalt thou eat thereof.", "webster": "Take thou also to thee wheat, and barley, and beans, and lentils, and millet, and fitches, and put them in one vessel, and make thee bread thereof, [according] to the number of the days that thou shalt lie upon thy side, three hundred and ninety days shalt thou eat of it.", "vulgate": "et tu sume tibi frumentum et hordeum et fabam et lentem et milium et viciam et mittes ea in vas unum et facies tibi panes numero dierum quibus dormies super latus tuum trecentis et nonaginta diebus comedes illud;", "brenton": "Take thou also to thee wheat, and barley, and beans, and lentils, and millet, and bread-corn; and thou shalt cast them into one earthen vessel, and shalt make them into loaves for thyself; and thou shalt eat them a hundred and ninety days, according to the number of the days during which thou sleepest on thy side."}}, {"v": 10, "ref": "4:10", "o": "וּ/מַאֲכָֽלְ/ךָ֙ אֲשֶׁ֣ר תֹּאכֲלֶ֔/נּוּ בְּ/מִשְׁק֕וֹל עֶשְׂרִ֥ים שֶׁ֖קֶל לַ/יּ֑וֹם מֵ/עֵ֥ת עַד עֵ֖ת תֹּאכֲלֶֽ/נּוּ", "en": {"kjv": "And thy meat which thou shalt eat shall be by weight, twenty shekels a day: from time to time shalt thou eat it.", "web": "Your food which you shall eat shall be by weight, twenty shekels a day: from time to time you shall eat it.", "bsb": "You are to weigh out twenty shekels of food to eat each day, and you are to eat it at set times.", "asv": "And thy food which thou shalt eat shall be by weight, twenty shekels a day: from time to time shalt thou eat it.", "ylt": "And thy food that thou dost eat is by weight, twenty shekels daily; from time to time thou dost eat it.", "dra": "And thy meat that thou shalt eat, shall be in weight twenty staters a day: from time to time thou shalt eat it.", "bbe": "And you are to take your food by weight, twenty shekels a day: you are to take it at regular times.", "geneva": "And the meate, whereof thou shalt eate, shalbe by weight, euen twenty shekels a day: and from time to time shalt thou eate thereof.", "wycliffe": "Forsothe thi mete, which thou schalt ete, schal be in weiyte twenti staters in a dai; fro tyme til to tyme thou schalt ete it.", "rotherham": "and thy food which thou shalt eat shall be by weight twenty shekels a day,— from time to time, shalt thou eat it;", "darby": "And thy meat which thou shalt eat shall be by weight, twenty shekels a day: from time to time shalt thou eat it.", "twenty": "", "jps": "And thy food which thou shalt eat shall be by weight, twenty shekels a day; from time to time shalt thou eat it.", "acv": "And thy food which thou shall eat shall be by weight, twenty shekels a day. Thou shall eat it from time to time.", "anderson": "", "haweis": "", "noyes": "And thy food which thou eatest shall be by weight, twenty shekels a day; from time to time shalt thou eat it.", "webster": "And thy food which thou shalt eat [shall be] by weight, twenty shekels a day: from time to time shalt thou eat it.", "vulgate": "cibus autem tuus quo vesceris erit in pondere viginti stateres in die a tempore usque ad tempus comedes illud;", "brenton": "And thou shalt eat thy food by weight, twenty shekels a day: from time to time shalt thou eat them."}}, {"v": 11, "ref": "4:11", "o": "וּ/מַ֛יִם בִּ/מְשׂוּרָ֥ה תִשְׁתֶּ֖ה שִׁשִּׁ֣ית הַ/הִ֑ין מֵ/עֵ֥ת עַד עֵ֖ת תִּשְׁתֶּֽה", "en": {"kjv": "Thou shalt drink also water by measure, the sixth part of an hin: from time to time shalt thou drink.", "web": "You shall drink water by measure, the sixth part of a hin: from time to time you shall drink.", "bsb": "You are also to measure out a sixth of a hin of water to drink, and you are to drink it at set times.", "asv": "And thou shalt drink water by measure, the sixth part of a hin: from time to time shalt thou drink.", "ylt": "`And water by measure thou dost drink, a sixth part of the hin; from time to time thou dost drink it .", "dra": "And thou shalt drink water by measure, the sixth part of a hin: from time to time thou shalt drink it,", "bbe": "And you are to take water by measure, the sixth part of a hin: you are to take it at regular times.", "geneva": "Thou shalt drinke also water by measure, euen the sixt part of an Hin: from time to time shalt thou drinke.", "wycliffe": "And thou schalt drynke watir in mesure, the sixte part of hyn; fro tyme til to tyme thou schalt drynke it.", "rotherham": "and water by measure, shalt thou drink the sixth part of a hin,-from time to time shalt thou drink;", "darby": "And thou shalt drink water by measure, the sixth part of a hin: from time to time shalt thou drink.", "twenty": "", "jps": "Thou shalt drink also water by measure, the sixth part of a hin; from time to time shalt thou drink.", "acv": "And thou shall drink water by measure, the sixth part of a hin. Thou shall drink from time to time.", "anderson": "", "haweis": "", "noyes": "Thou shalt also drink water by measure, the sixth part of a hin; from time to time shalt thou drink.", "webster": "Thou shalt drink also water by measure, the sixth part of a hin: from time to time shalt thou drink.", "vulgate": "et aquam in mensura bibes sextam partem hin a tempore usque ad tempus bibes illud;", "brenton": "And thou shalt drink water by measure, even from time to time thou shalt drink the sixth part of a hin."}}, {"v": 12, "ref": "4:12", "o": "וְ/עֻגַ֥ת שְׂעֹרִ֖ים תֹּֽאכֲלֶ֑/נָּה וְ/הִ֗יא בְּ/גֶֽלְלֵי֙ צֵאַ֣ת הָֽ/אָדָ֔ם תְּעֻגֶ֖/נָה לְ/עֵינֵי/הֶֽם", "en": {"kjv": "And thou shalt eat it as barley cakes, and thou shalt bake it with dung that cometh out of man, in their sight.", "web": "You shall eat it as barley cakes, and you shall bake it in their sight with dung that comes out of man.", "bsb": "And you shall eat the food as you would a barley cake, after you bake it over dried human excrement in the sight of the people.”", "asv": "And thou shalt eat it as barley cakes, and thou shalt bake it in their sight with dung that cometh out of man.", "ylt": "A barley-cake thou dost eat it, and it with dung--the filth of man--thou dost bake before their eyes.", "dra": "And thou shalt eat it as barley bread baked under the ashes: and thou shalt cover it, in their sight, with the dung that cometh out of a man.", "bbe": "And let your food be barley cakes, cooking it before their eyes with the waste which comes out of a man.", "geneva": "And thou shalt eate it as barley cakes, and thou shalt bake it in the dongue that commeth out of man, in their sight.", "wycliffe": "And thou schalt ete it as barli breed bakun vndur the aischis; and with `a toord that goith out of a man thou schalt hile, it bifore the iyen of hem.", "rotherham": "and as a barley cake, shalt thou eat it,—and the same with dung proceeding from man, shalt thou bake, before their eyes.", "darby": "And thou shalt eat it [as] barley-cake, and thou shalt bake it in their sight with dung that cometh out of man.", "twenty": "", "jps": "And thou shalt eat it as barley cakes, and thou shalt bake it in their sight with dung that cometh out of man.'", "acv": "And thou shall eat it as barley cakes, and thou shall bake it in their sight with dung that comes out of man.", "anderson": "", "haweis": "", "noyes": "Thou shalt also eat barley-cakes; and with dung that cometh out of man shalt thou bake them in their sight.", "webster": "And thou shalt eat it [as] barley cakes, and thou shalt bake it with human excrement in their sight.", "vulgate": "et quasi subcinericium hordiacium comedes illud et stercore quod egredietur de homine operies illud in oculis eorum;", "brenton": "And thou shalt eat them as a barley cake: thou shalt bake them before their eyes in man's dung."}}, {"v": 13, "ref": "4:13", "o": "וַ/יֹּ֣אמֶר יְהוָ֔ה כָּ֣כָה יֹאכְל֧וּ בְנֵֽי יִשְׂרָאֵ֛ל אֶת לַחְמָ֖/ם טָמֵ֑א בַּ/גּוֹיִ֕ם אֲשֶׁ֥ר אַדִּיחֵ֖/ם שָֽׁם", "en": {"kjv": "And the Lord said, Even thus shall the children of Israel eat their defiled bread among the Gentiles, whither I will drive them.", "web": "Yahweh said, Even thus shall the children of Israel eat their bread unclean, among the nations where I will drive them.", "bsb": "Then the LORD said, “This is how the Israelites will eat their defiled bread among the nations to which I will banish them.”", "asv": "And Jehovah said, Even thus shall the children of Israel eat their bread unclean, among the nations whither I will drive them.", "ylt": "And Jehovah saith, `Thus do the sons of Israel eat their defiled bread among the nations whither I drive them.'", "dra": "And the Lord said: So shall the children of Israel eat their bread all filthy among the nations whither I will cast them out.", "bbe": "And the Lord said, Even so the children of Israel will have unclean bread for their food among the nations where I am driving them.", "geneva": "And the Lord said, So shall the children of Israel eate their defiled bread among the Gentiles, whither I will cast them.", "wycliffe": "The Lord seith these thingis, So the sones of Israel schulen ete her breed defoulid among hethene men, to whiche Y schal caste hem out.", "rotherham": "Then said Yahweh, In like manner, shall the sons of Israel eat their bread defiled,—among the nations whither I will drive them.", "darby": "And Jehovah said, So shall the children of Israel eat their bread unclean among the nations whither I will drive them.", "twenty": "", "jps": "And HaShem said: 'Even thus shall the children of Israel eat their bread unclean, among the nations whither I will drive them.'", "acv": "And Jehovah said, Even thus shall the sons of Israel eat their bread unclean among the nations where I will drive them.", "anderson": "", "haweis": "", "noyes": "And Jehovah said, Even thus shall the sons of Israel eat their polluted food among the nations, whither I will drive them.", "webster": "And the LORD said, Even thus shall the children of Israel eat their defiled bread among the Gentiles, whither I will drive them.", "vulgate": "et dixit Dominus sic comedent filii Israhel panem suum pollutum inter gentes ad quas eiciam eos;", "brenton": "And thou shalt say, Thus saith the Lord God of Israel; Thus shall the children of Israel eat unclean things among the Gentiles."}}, {"v": 14, "ref": "4:14", "o": "וָ/אֹמַ֗ר אֲהָהּ֙ אֲדֹנָ֣/י יְהוִ֔ה הִנֵּ֥ה נַפְשִׁ֖/י לֹ֣א מְטֻמָּאָ֑ה וּ/נְבֵלָ֨ה וּ/טְרֵפָ֤ה לֹֽא אָכַ֨לְתִּי֙ מִ/נְּעוּרַ֣/י וְ/עַד עַ֔תָּה וְ/לֹא בָ֥א בְּ/פִ֖/י בְּשַׂ֥ר פִּגּֽוּל", "en": {"kjv": "Then said I, Ah Lord God! behold, my soul hath not been polluted: for from my youth up even till now have I not eaten of that which dieth of itself, or is torn in pieces; neither came there abominable flesh into my mouth.", "web": "Then I said, Ah Lord Yahweh! behold, my soul has not been polluted; for from my youth up even until now have I not eaten of that which dies of itself, or is torn of animals; neither came there abominable flesh into my mouth.", "bsb": "“Ah, Lord GOD,” I said, “I have never defiled myself. From my youth until now I have not eaten anything found dead or mauled by wild beasts. No unclean meat has ever entered my mouth.”", "asv": "Then said I, Ah Lord Jehovah! behold, my soul hath not been polluted; for from my youth up even till now have I not eaten of that which dieth of itself, or is torn of beasts; neither came there abominable flesh into my mouth.", "ylt": "And I say, `Ah, Lord Jehovah, lo, my soul is not defiled, and carcase, and torn thing, I have not eaten from my youth, even till now; nor come into my mouth hath abominable flesh.'", "dra": "And I said: Ah, ah, ah, O Lord God, behold my soul hath not been defiled, and from my infancy even till now, I have not eaten any thing that died of itself, or was torn by beasts, and no unclean flesh hath entered into my mouth.", "bbe": "Then I said, Ah, Lord! see, my soul has never been unclean, and I have never taken as my food anything which has come to a natural death or has been broken by beasts, from the time when I was young even till now; no disgusting flesh has ever come into my mouth.", "geneva": "Then said I, Ah, Lord God, beholde, my soule hath not bene polluted: for from my youth vp, euen vnto this houre, I haue not eaten of a thing dead, or torne in pieces, neither came there any vncleane flesh in my mouth.", "wycliffe": "And Y seide, A! A! A! Lord God, lo! my soule is not defoulid, and fro my yong childhed til to now Y eet not a thing deed bi it silf, and to-rent of beestis; and al vnclene fleisch entride not in to my mouth.", "rotherham": "Then said, I, Ah! My Lord. Yahweh, lo! my person, hath not been defiled: neither of what hath died of itself nor of what hath been torn in pieces: have I eaten, from my youthful days even unto now, neither hath come into my mouth the flesh of a foul thing.", "darby": "Then said I, Ah, Lord Jehovah! behold, my soul hath not been defiled, and from my youth up even until now have I not eaten of that which dieth of itself, or of that which is torn; neither came there abominable flesh into my mouth.", "twenty": "", "jps": "Then said I: 'Ah L-rd GOD! behold, my soul hath not been polluted; for from my youth up even till now have I not eaten of that which dieth of itself, or is torn of beasts; neither came there abhorred flesh into my mouth.'", "acv": "Then I said, Ah lord Jehovah! Behold, my soul has not been polluted. For from my youth up even till now I have not eaten of that which dies of itself, or is torn of beasts, neither has abominable flesh come into my mouth.", "anderson": "", "haweis": "", "noyes": "Then said I: Ah! Lord Jehovah, behold, I have never been polluted; for from my youth until now have I not eaten that which died of itself, or was torn in pieces; neither hath unclean food come into my mouth.", "webster": "Then said I, Ah Lord GOD! behold, my soul hath not been polluted: for from my youth even till now have I not eaten of that which dieth of itself, or is torn in pieces; neither hath abominable flesh come into my mouth.", "vulgate": "et dixi ha ha ha Domine Deus ecce anima mea non est polluta et morticinum et laceratum a bestiis non comedi ab infantia mea usque nunc et non est ingressa os meum omnis caro inmunda;", "brenton": "Then I said, Not so, Lord God of Israel: surely my soul has not been defiled with uncleanness; nor have I eaten, that which died of itself or was torn of beasts from my birth until now; neither has any corrupt flesh entered into my mouth."}}, {"v": 15, "ref": "4:15", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י רְאֵ֗ה נָתַ֤תִּֽי לְ/ךָ֙ אֶת צפועי צְפִיעֵ֣י הַ/בָּקָ֔ר תַּ֖חַת גֶּלְלֵ֣י הָֽ/אָדָ֑ם וְ/עָשִׂ֥יתָ אֶֽת לַחְמְ/ךָ֖ עֲלֵי/הֶֽם", "en": {"kjv": "Then he said unto me, Lo, I have given thee cow’s dung for man’s dung, and thou shalt prepare thy bread therewith.", "web": "Then he said to me, Behold, I have given you cow’s dung for man’s dung, and you shall prepare your bread on it.", "bsb": "“Look,” He replied, “I will let you use cow dung instead of human excrement, and you may bake your bread over that.”", "asv": "Then he said unto me, See, I have given thee cow’s dung for man’s dung, and thou shalt prepare thy bread thereon.", "ylt": "And He saith unto me, `See, I have given to thee bullock's dung instead of man's dung, and thou hast made thy bread by it.'", "dra": "And he said to me: Behold I have given thee neat's dung for man's dung, and thou shalt make thy bread therewith.", "bbe": "Then he said to me, See, I have given you cow's waste in place of man's waste, and you will make your bread ready on it.", "geneva": "Then he said vnto me, Loe, I haue giuen thee bullockes dongue for mans dongue, and thou shalt prepare thy bread therewith.", "wycliffe": "And he seide to me, Lo! Y haue youe to thee the dung of oxis for mennus toordis; and thou schalt make thi breed with it.", "rotherham": "So then he said unto me, See I have granted thee cow’s dung for man’s dung,—and thou shalt prepare thy bread thereupon.", "darby": "And he said unto me, See, I have given thee cow's dung for man's dung, and thou shalt prepare thy bread therewith.", "twenty": "", "jps": "Then He said unto me: 'See, I have given thee cow's dung for man's dung, and thou shalt prepare thy bread thereon.'", "acv": "Then he said to me, See, I have given thee cow's dung for man's dung, and thou shall prepare thy bread of it.", "anderson": "", "haweis": "", "noyes": "Then he said to me: Behold, I give thee cow’s dung for man’s dung; and with that shalt thou prepare thy food.", "webster": "Then he said to me, Lo, I have given thee cow's dung for man's dung, and thou shalt prepare thy bread with them.", "vulgate": "et dixit ad me ecce dedi tibi fimum boum pro stercoribus humanis et facies panem tuum in eo;", "brenton": "And he said to me, Behold, I have given thee dung of oxen instead of man's dung, and thou shalt prepare thy loaves upon it."}}, {"v": 16, "ref": "4:16", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י בֶּן אָדָם֙ הִנְ/נִ֨י שֹׁבֵ֤ר מַטֵּה לֶ֨חֶם֙ בִּ/יר֣וּשָׁלִַ֔ם וְ/אָכְלוּ לֶ֥חֶם בְּ/מִשְׁקָ֖ל וּ/בִ/דְאָגָ֑ה וּ/מַ֕יִם בִּ/מְשׂוּרָ֥ה וּ/בְ/שִׁמָּמ֖וֹן יִשְׁתּֽוּ", "en": {"kjv": "Moreover he said unto me, Son of man, behold, I will break the staff of bread in Jerusalem: and they shall eat bread by weight, and with care; and they shall drink water by measure, and with astonishment:", "web": "Moreover he said to me, Son of man, behold, I will break the staff of bread in Jerusalem: and they shall eat bread by weight, and with fearfulness; and they shall drink water by measure, and in dismay:", "bsb": "Then He told me, “Son of man, I am going to cut off the supply of food in Jerusalem. They will anxiously eat bread rationed by weight, and in despair they will drink water by measure.", "asv": "Moreover he said unto me, Son of man, behold, I will break the staff of bread in Jerusalem: and they shall eat bread by weight, and with fearfulness; and they shall drink water by measure, and in dismay:", "ylt": "And He saith unto me, `Son of man, lo, I am breaking the staff of bread in Jerusalem, and they have eaten bread by weight and with fear; and water by measure and with astonishment, they do drink;", "dra": "And he said to me: Son of man: Behold, I will break in pieces the staff of bread in Jerusalem: and they shall eat bread by weight, and with care: and they shall drink water by measure, and in distress.", "bbe": "And he said to me, Son of man, see, I will take away from Jerusalem her necessary bread: they will take their bread by weight and with care, measuring out their drinking-water with fear and wonder:", "geneva": "Moreouer, he said vnto me, Sonne of man, beholde, I will breake the staffe of bread in Ierusalem, and they shall eate bread by weight, and with care, and they shall drinke water by measure, and with astonishment.", "wycliffe": "And he seide to me, Sone of man, lo! Y schal al to-breke the staf of breed in Jerusalem, and thei schulen ete her breed in weiyte and in bisynesse, and thei schulen drynke water in mesure and in angwisch;", "rotherham": "And he said unto me, Son of man Behold me! breaking the staff of bread in Jerusalem, So shall they eat bread by weight and with anxious care, And water by measure, and in astonishment, shall they drink:", "darby": "And he said unto me, Son of man, behold, I break the staff of bread in Jerusalem; and they shall eat bread by weight, and with anxiety; and they shall drink water by measure, and with astonishment:", "twenty": "", "jps": "Moreover He said unto me: 'Son of man, behold, I will break the staff of bread in Jerusalem, and they shall eat bread by weight, and with anxiety; and they shall drink water by measure, and in appalment;", "acv": "Moreover he said to me, Son of man, behold, I will break the staff of bread in Jerusalem, and they shall eat bread by weight, and with fearfulness, and they shall drink water by measure, and in dismay,", "anderson": "", "haweis": "", "noyes": "And he said to me: Son of man, behold, I will break the staff of bread in Jerusalem, and they shall eat bread by weight and with care, and they shall drink water by measure and in amazement;", "webster": "Moreover he said to me, Son of man, behold, I will break the staff of bread in Jerusalem: and they shall eat bread by weight, and with care; and they shall drink water by measure, and with astonishment.", "vulgate": "et dixit ad me fili hominis ecce ego conteram baculum panis in Hierusalem et comedent panem in pondere et in sollicitudine et aquam in mensura et in angustia bibent;", "brenton": "And he said to me, Son of man, behold, I break the support of bread in Jerusalem: and they shall eat bread by weight and in want; and shall drink water by measure, and in a state of ruin:"}}, {"v": 17, "ref": "4:17", "o": "לְמַ֥עַן יַחְסְר֖וּ לֶ֣חֶם וָ/מָ֑יִם וְ/נָשַׁ֨מּוּ֙ אִ֣ישׁ וְ/אָחִ֔י/ו וְ/נָמַ֖קּוּ בַּ/עֲוֺנָֽ/ם", "en": {"kjv": "That they may want bread and water, and be astonied one with another, and consume away for their iniquity.", "web": "that they may want bread and water, and be dismayed one with another, and pine away in their iniquity.", "bsb": "So they will lack food and water; they will be appalled at the sight of one another wasting away in their iniquity.", "asv": "that they may want bread and water, and be dismayed one with another, and pine away in their iniquity.", "ylt": "so that they lack bread and water, and have been astonished one with another, and been consumed in their iniquity.", "dra": "So that when bread and water fail, every man may fall against his brother, and they may pine away in their iniquities.", "bbe": "So that they may be in need of bread and water and be wondering at one another, wasting away in their sin.", "geneva": "Because that bread and water shall faile, they shalbe astonied one with another, and shall consume away for their iniquitie.", "wycliffe": "that whanne breed and watir failen, eche man falle doun to his brother, and thei faile in her wickidnessis.", "rotherham": "that they may lack bread and water and be astonished one with another, and pine away in their punishment.", "darby": "because bread and water shall fail them, and they shall be astonied one with another, and waste away in their iniquity.", "twenty": "", "jps": "that they may want bread and water, and be appalled one with another, and pine away in their iniquity.", "acv": "that they may lack bread and water, and be dismayed one with another, and pine away in their iniquity.", "anderson": "", "haweis": "", "noyes": "so that they shall be in want of bread and water, and be astonished one at another, and consume away for their iniquity.", "webster": "That they may want bread and water, and be astonished one with another, and consume away for their iniquity.", "vulgate": "ut deficientibus pane et aqua corruat unusquisque ad fratrem suum et contabescant in iniquitatibus suis;", "brenton": "that they may want bread and water; and a man and his brother shall be brought to ruin, and they shall pine away in their iniquities."}}]}, {"c": 5, "verses": [{"v": 1, "ref": "5:1", "o": "וְ/אַתָּ֨ה בֶן אָדָ֜ם קַח לְ/ךָ֣ חֶ֣רֶב חַדָּ֗ה תַּ֤עַר הַ/גַּלָּבִים֙ תִּקָּחֶ֣/נָּה לָּ֔/ךְ וְ/הַעֲבַרְתָּ֥ עַל רֹאשְׁ/ךָ֖ וְ/עַל זְקָנֶ֑/ךָ וְ/לָקַחְתָּ֥ לְ/ךָ֛ מֹאזְנֵ֥י מִשְׁקָ֖ל וְ/חִלַּקְתָּֽ/ם", "en": {"kjv": "And thou, son of man, take thee a sharp knife, take thee a barber’s razor, and cause it to pass upon thine head and upon thy beard: then take thee balances to weigh, and divide the hair.", "web": "You, son of man, take a sharp sword; You shall take it as a barber’s razor to you, and shall cause it to pass on your head and on your beard: then take balances to weigh, and divide the hair.", "bsb": "“As for you, son of man, take a sharp sword, use it as a barber’s razor, and shave your head and beard. Then take a set of scales and divide the hair.", "asv": "And thou, son of man, take thee a sharp sword; as a barber’s razor shalt thou take it unto thee, and shalt cause it to pass upon thy head and upon thy beard: then take thee balances to weigh, and divide the hair.", "ylt": "`And thou, son of man, take to thee a sharp weapon, the barber's razor thou dost take to thee, and thou hast caused it to pass over thy head, and over thy beard, and thou hast taken to thee weighing scales, and apportioned them.", "dra": "And thou, son of man, take thee a sharp knife that shaveth the hair: and cause it to pass over thy head, and over thy beard: and take thee a balance to weigh in, and divide the hair.", "bbe": "And you, son of man, take a sharp sword, using it like a haircutter's blade, and making it go over your head and the hair of your chin: and take scales for separating the hair by weight.", "geneva": "And thou sonne of man, take thee a sharpe knife, or take thee a barbours rasor and cause it to passe vpon thine head, and vpon thy beard: then take thee balances to weigh, and deuide the heare.", "wycliffe": "And thou, sone of man, take to thee a scharp swerd, schauynge heeris; and thou schalt take it, and schalt leede it bi thin heed, and bi thi berd. And thou schalt take to thee a balaunce of weiyte, and thou schalt departe tho.", "rotherham": "Thou therefore son of man Take thee a sharp cutting instrument, a barber’s razor, shalt thou take thee, and shalt cause it to pass upon thy head and upon thy chin,—and shalt take the balances for weighing, and shalt divide the hair.", "darby": "And thou, son of man, take thee a sharp knife; a barber's razor shalt thou take; and cause it to pass upon thy head and upon thy beard: and thou shalt take balances to weigh, and divide the [hair].", "twenty": "", "jps": "And thou, son of man, take thee a sharp sword, as a barber's razor shalt thou take it unto thee, and cause it to pass upon thy head and upon thy beard; then take thee balances to weigh, and divide the hair.", "acv": "And thou, son of man, take thee a sharp sword. As a barber's razor thou shall take it to thee, and shall cause it to pass upon thy head and upon thy beard. Then take thee balances to weigh and divide the hair.", "anderson": "", "haweis": "", "noyes": "And thou, son of man, take thee a sharp instrument, even a barber’s razor, and cause it to pass upon thy head and thy beard; and take thee weighing-balances, and divide the hair.", "webster": "And thou, son of man, take thee a sharp knife, take thee a barber's razor, and cause [it] to pass upon thy head and upon thy beard: then take to thee balances to weigh, and divide the [hair].", "vulgate": "et tu fili hominis sume tibi gladium acutum radentem pilos adsumes eum et duces per caput tuum et per barbam tuam et adsumes tibi stateram ponderis et divides eos;", "brenton": "And thou, son of man, take thee a sword sharper than a barber's razor; thou shalt procure it for thyself, and shalt bring it upon thine head, and upon thy beard: and thou shalt take a pair of scales, and shalt separate the hair."}}, {"v": 2, "ref": "5:2", "o": "שְׁלִשִׁ֗ית בָּ/א֤וּר תַּבְעִיר֙ בְּ/ת֣וֹךְ הָ/עִ֔יר כִּ/מְלֹ֖את יְמֵ֣י הַ/מָּצ֑וֹר וְ/לָֽקַחְתָּ֣ אֶת הַ/שְּׁלִשִׁ֗ית תַּכֶּ֤ה בַ/חֶ֨רֶב֙ סְבִ֣יבוֹתֶ֔י/הָ וְ/הַ/שְּׁלִשִׁית֙ תִּזְרֶ֣ה לָ/ר֔וּחַ וְ/חֶ֖רֶב אָרִ֥יק אַחֲרֵי/הֶֽם", "en": {"kjv": "Thou shalt burn with fire a third part in the midst of the city, when the days of the siege are fulfilled: and thou shalt take a third part, and smite about it with a knife: and a third part thou shalt scatter in the wind; and I will draw out a sword after them.", "web": "A third part you shall burn in the fire in the midst of the city, when the days of the siege are fulfilled; and you shall take a third part, and strike with the sword around it; and a third part you shall scatter to the wind, and I will draw out a sword after them.", "bsb": "When the days of the siege have ended, you are to burn up a third of the hair inside the city; you are also to take a third and slash it with the sword all around the city; and you are to scatter a third to the wind. For I will unleash a sword behind them.", "asv": "A third part shalt thou burn in the fire in the midst of the city, when the days of the siege are fulfilled; and thou shalt take a third part, and smite with the sword round about it; and a third part thou shalt scatter to the wind, and I will draw out a sword after them.", "ylt": "A third part with fire thou dost burn in the midst of the city, at the fulness of the days of the siege; and thou hast taken the third part, thou dost smite with a weapon round about it; and the third part thou dost scatter to the wind, and a weapon I draw out after them.", "dra": "A third part thou shalt burn with fire in the midst of the city, according to the fulfilling of the days of the siege: and thou shalt take a third part, and cut it in pieces with the knife all round about: and the other third part thou shalt scatter in the wind, and I will draw out the sword after them.", "bbe": "You are to have a third part burned with fire inside the town, when the days of the attack are ended; and a third part you are to take and give blows with the sword round about it; and give a third part for the wind to take away, and let loose a sword after them.", "geneva": "Thou shalt burne with fire the thirde part in the middes of the citie, when the dayes of the siege are fulfilled, and thou shalt take the other thirde part, and smite about it with a knife, and the last thirde part thou shalt scatter in the winde, and I will drawe out a sworde after them.", "wycliffe": "Thou schalt brenne the thridde part with fier in the myddis of the citee, bi the fillyng of daies of bisegyng. And thou schalt take the thridde part, and schalt kitte bi swerd in the cumpas therof. But thou schalt scatere `the tother thridde part in to the wynd; and Y schal make nakid a swerd aftir hem.", "rotherham": "A third part in the fire, shalt thou burn in the midst of the city, when the days of the siege are fulfilled,—and thou shalt take a third part, thou shalt smite it with the cuting instrument round about it, and a third part, shalt thou scatter to the wind, and, a sword, will I, make bare after them;", "darby": "A third part shalt thou burn in the fire in the midst of the city, when the days of the siege are fulfilled; and thou shalt take a third part, [and] smite about it with a knife; and a third part thou shalt scatter to the wind, and I will draw out a sword after them.", "twenty": "", "jps": "A third part shalt thou burn in the fire in the midst of the city, when the days of the siege are fulfilled; and thou shalt take a third part, and smite it with the sword round about her; and a third part thou shalt scatter to the wind, and I will draw out a sword after them.", "acv": "A third part thou shall burn in the fire in the midst of the city when the days of the siege are fulfilled, and thou shall take a third part, and smite with the sword round about it, and a third part thou shall scatter to the wind. And I will draw out a sword after them.", "anderson": "", "haweis": "", "noyes": "A third part shalt thou burn with fire in the midst of the city, when the days of the siege are fulfilled; and thou shalt take a third part and smite it round about with the sword; and a third part shalt thou scatter in the wind, and I will draw out a sword after them.", "webster": "Thou shalt burn with fire a third part in the midst of the city, when the days of the siege are fulfilled: and thou shalt take a third part, [and] smite about it with a knife: and a third part thou shalt scatter in the wind; and I will draw out a sword after them.", "vulgate": "tertiam partem igni conbures in medio civitatis iuxta conpletionem dierum obsidionis et adsumens tertiam partem concides gladio in circuitu eius tertiam vero aliam disperges in ventum et gladium nudabo post eos;", "brenton": "A fourth part thou shalt burn in the fire in the midst of the city, at the fulfillment of the days of the siege: and thou shalt take a fourth part, and burn it up in the midst of it: and a fourth part thou shalt cut with a sword round about it: and a fourth part thou shalt scatter to the wind; and I will draw out a sword after them."}}, {"v": 3, "ref": "5:3", "o": "וְ/לָקַחְתָּ֥ מִ/שָּׁ֖ם מְעַ֣ט בְּ/מִסְפָּ֑ר וְ/צַרְתָּ֥ אוֹתָ֖/ם בִּ/כְנָפֶֽי/ךָ", "en": {"kjv": "Thou shalt also take thereof a few in number, and bind them in thy skirts.", "web": "You shall take of it a few in number, and bind them in your skirts.", "bsb": "But you are to take a few strands of hair and secure them in the folds of your garment.", "asv": "And thou shalt take thereof a few in number, and bind them in thy skirts.", "ylt": "And thou hast taken thence a few in number--and hast bound them in thy skirts;", "dra": "And thou shalt take thereof a small number: and shalt bind them in the skirt of thy cloak.", "bbe": "And take from them a small number of hairs, folding them in your skirts.", "geneva": "Thou shalt also take thereof a fewe in nomber, and binde them in thy lappe.", "wycliffe": "And thou schalt take therof a litil noumbre, and thou schalt bynde tho in the hiynesse of thi mentil.", "rotherham": "and thou shalt take from thence, a few in number,—and shalt bind them in thy skirts;", "darby": "And thou shalt take thereof a few in number, and bind them in thy skirts;", "twenty": "", "jps": "Thou shalt also take thereof a few by number, and bind them in thy skirts.", "acv": "And thou shall take from it a few in number, and bind them in thy skirts.", "anderson": "", "haweis": "", "noyes": "Thou shalt also take thereof a small number, and bind them in thy skirts.", "webster": "Thou shalt also take of them a few in number, and bind them in thy skirts.", "vulgate": "et sumes inde parvum numerum et ligabis eos in summitate pallii tui;", "brenton": "And thou shalt take thence a few in number, and shalt wrap them in the fold of thy garment."}}, {"v": 4, "ref": "5:4", "o": "וּ/מֵ/הֶם֙ ע֣וֹד תִּקָּ֔ח וְ/הִשְׁלַכְתָּ֤ אוֹתָ/ם֙ אֶל תּ֣וֹךְ הָ/אֵ֔שׁ וְ/שָׂרַפְתָּ֥ אֹתָ֖/ם בָּ/אֵ֑שׁ מִמֶּ֥/נּוּ תֵצֵא אֵ֖שׁ אֶל כָּל בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Then take of them again, and cast them into the midst of the fire, and burn them in the fire; for thereof shall a fire come forth into all the house of Israel.", "web": "Of these again you shall take, and cast them into the midst of the fire, and burn them in the fire; from it shall a fire come out into all the house of Israel.", "bsb": "Again, take a few of these, throw them into the fire, and burn them. From there a fire will spread to the whole house of Israel.", "asv": "And of these again shalt thou take, and cast them into the midst of the fire, and burn them in the fire; therefrom shall a fire come forth into all the house of Israel.", "ylt": "and of them thou dost take again, and hast cast them unto the midst of the fire, and hast burned them in the fire--out of it cometh forth a fire unto all the house of Israel.", "dra": "And thou shalt take of them again, and shalt cast them in the midst of the fire, and shalt burn them with fire: and out of it shall come forth a fire into all the house of Israel.", "bbe": "And again take some of these and put them in the fire, burning them up in the fire; and say to all the children of Israel,", "geneva": "Then take of them againe and cast them into the middes of the fire, and burne them in the fire: for thereof shall a fire come foorth into all the house of Israel.", "wycliffe": "And eft thou schalt take of hem, and thou schalt caste forth hem in to the myddis of the fier. And thou schalt brenne hem in fier; and fier schal go out of that in to al the hous of Israel.", "rotherham": "and of them, again take, and cast them into the midst of the fire, and burn them in the fire,-therefrom, shall go forth a fire unto all the house of Israel.", "darby": "and thou shalt take of these again, and cast them into the midst of the fire, and burn them in the fire: from it shall a fire come forth against all the house of Israel.", "twenty": "", "jps": "And of them again shalt thou take, and cast them into the midst of the fire, and burn them in the fire; therefrom shall a fire come forth into all the house of Israel.", "acv": "And of these again thou shall take, and cast them into the midst of the fire, and burn them in the fire. From there a fire shall come forth into all the house of Israel.", "anderson": "", "haweis": "", "noyes": "And of these again take some and cast them into the fire, and burn them in the fire. From them shall a fire come forth upon the whole house of Israel.", "webster": "Then take of them again, and cast them into the midst of the fire, and burn them in the fire: from which a fire shall come forth into all the house of Israel.", "vulgate": "et ex eis rursum tolles et proicies in medio ignis et conbures eos igni ex eo egredietur ignis in omnem domum Israhel;", "brenton": "And thou shalt take of these again, and cast them into the midst of the fire, and burn them up with fire: from thence shall come forth fire; and thou shalt say to the whole house of Israel,"}}, {"v": 5, "ref": "5:5", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהֹוִ֔ה זֹ֚את יְר֣וּשָׁלִַ֔ם בְּ/ת֥וֹךְ הַ/גּוֹיִ֖ם שַׂמְתִּ֑י/הָ וּ/סְבִיבוֹתֶ֖י/הָ אֲרָצֽוֹת", "en": {"kjv": "Thus saith the Lord God; This is Jerusalem: I have set it in the midst of the nations and countries that are round about her.", "web": "Thus says the Lord Yahweh: This is Jerusalem; I have set her in the midst of the nations, and countries are around her.", "bsb": "This is what the Lord GOD says: ‘This is Jerusalem, which I have set in the center of the nations, with countries all around her.", "asv": "Thus saith the Lord Jehovah: This is Jerusalem; I have set her in the midst of the nations, and countries are round about her.", "ylt": "Thus said the Lord Jehovah: this is Jerusalem, In the midst of the nations I have set her, And round about her are the lands.", "dra": "Thus saith the Lord God: This is Jerusalem, I have set her in the midst of the nations, and the countries round about her.", "bbe": "This is what the Lord has said: This is Jerusalem: I have put her among the nations, and countries are round her on every side;", "geneva": "Thus saith the Lord God, This is Ierusalem: I haue set it in the middes of the nations and countreyes, that are rounde about her.", "wycliffe": "The Lord God seith these thingis, This is Jerusalem; Y haue sette it in the myddis of hethene men, and londis in the cumpas therof.", "rotherham": "Thus, saith My Lord, Yahweh, This, is Jerusalem, In the midst of the nations, I placed her,— and of the countries round about her;", "darby": "Thus saith the Lord Jehovah: This is Jerusalem: I have set her in the midst of the nations, and the countries are round about her.", "twenty": "", "jps": "Thus saith the L-rd GOD: This is Jerusalem! I have set her in the midst of the nations, and countries are round about her.", "acv": "Thus says the lord Jehovah: This is Jerusalem. I have set her in the midst of the nations, and countries are round about her.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: This is Jerusalem; in the midst of the nations have I set her, and countries are round about her.", "webster": "Thus saith the Lord GOD; This [is] Jerusalem: I have set it in the midst of the nations and countries [that are] around her.", "vulgate": "haec dicit Dominus Deus ista est Hierusalem in medio gentium posui eam et in circuitu eius terras;", "brenton": "Thus saith the Lord; This is Jerusalem: I have set her and the countries round about her in the midst of the nations."}}, {"v": 6, "ref": "5:6", "o": "וַ/תֶּ֨מֶר אֶת מִשְׁפָּטַ֤/י לְ/רִשְׁעָה֙ מִן הַ/גּוֹיִ֔ם וְ/אֶ֨ת חֻקּוֹתַ֔/י מִן הָ/אֲרָצ֖וֹת אֲשֶׁ֣ר סְבִיבוֹתֶ֑י/הָ כִּ֤י בְ/מִשְׁפָּטַ/י֙ מָאָ֔סוּ וְ/חֻקּוֹתַ֖/י לֹא הָלְכ֥וּ בָ/הֶֽם", "en": {"kjv": "And she hath changed my judgments into wickedness more than the nations, and my statutes more than the countries that are round about her: for they have refused my judgments and my statutes, they have not walked in them.", "web": "She has rebelled against my ordinances in doing wickedness more than the nations, and against my statutes more than the countries that are around her; for they have rejected my ordinances, and as for my statutes, they have not walked in them.", "bsb": "But she has rebelled against My ordinances more wickedly than the nations, and against My statutes worse than the countries around her. For her people have rejected My ordinances and have not walked in My statutes.’", "asv": "And she hath rebelled against mine ordinances in doing wickedness more than the nations, and against my statutes more than the countries that are round about her; for they have rejected mine ordinances, and as for my statutes, they have not walked in them.", "ylt": "And she changeth My judgments into wickedness more than the nations, And My statutes more than the lands that are round about her, For against My judgments they have kicked, And My statutes--they have not walked in them.", "dra": "And she hath despised my judgments, so as to be more wicked than the Gentiles; and my commandments, more than the countries that are round about her: for they have cast off my judgments, and have not walked in my commandments.", "bbe": "And she has gone against my orders by doing evil more than the nations, and against my rules more than the countries round her: for they have given up my orders, and as for my rules, they have not gone in the way of them.", "geneva": "And she hath changed my iudgements into wickednes more then the nations, and my statutes more then the countreis, that are round about her: for they haue refused my iudgemets and my statutes, and they haue not walked in them.", "wycliffe": "And it dispiside my domes, that it was more wickid than hethene men; and it dispiside my comaundementis more than londis that ben in the cumpas therof. For thei han cast awei my domes, and thei yeden not in my comaundementis.", "rotherham": "But she hath changed my regulations into lawlessness, more than the nations, And my statutes more than the countries which are round bout her, For my regulations, have they rejected, And in my statutes, have they not walked.", "darby": "And she hath rebelled against my judgments in wickedness more than the nations, and against my statutes more than the countries that are round about her: for mine ordinances have they refused; and my statutes, they have not walked in them.", "twenty": "", "jps": "And she hath rebelled against Mine ordinances in doing wickedness more than the nations, and against My statutes more than the countries that are round about her; for they have rejected Mine ordinances, and as for My statutes, they have not walked in them.", "acv": "And she has rebelled against my ordinances in doing wickedness more than the nations, and against my statutes more than the countries that are round about her, for they have rejected my ordinances, and as for my statutes, they have not walked in them.", "anderson": "", "haweis": "", "noyes": "But she hath wickedly resisted my ordinances more than the nations, and my statutes more than the countries, that are round about her. For they have refused my ordinances, and have not walked in my statutes.", "webster": "And she hath changed my judgments into wickedness more than the nations, and my statutes more than the countries that [are] around her: for they have refused my judgments and my statutes, they have not walked in them.", "vulgate": "et contempsit iudicia mea ut plus esset impia quam gentes et praecepta mea ultra quam terrae quae in circuitu eius sunt iudicia enim mea proiecerunt et in praeceptis meis non ambulaverunt;", "brenton": "And thou shalt declare mine ordinances to the lawless one from out of the nations; and my statutes to the sinful one of the countries round about her: because they have rejected mine ordinances, and have not walked in my statutes."}}, {"v": 7, "ref": "5:7", "o": "לָ/כֵ֞ן כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה יַ֤עַן הֲמָנְ/כֶם֙ מִן הַ/גּוֹיִם֙ אֲשֶׁ֣ר סְבִיבֽוֹתֵי/כֶ֔ם בְּ/חֻקּוֹתַ/י֙ לֹ֣א הֲלַכְתֶּ֔ם וְ/אֶת מִשְׁפָּטַ֖/י לֹ֣א עֲשִׂיתֶ֑ם וּֽ/כְ/מִשְׁפְּטֵ֧י הַ/גּוֹיִ֛ם אֲשֶׁ֥ר סְבִיבוֹתֵי/כֶ֖ם לֹ֥א עֲשִׂיתֶֽם", "en": {"kjv": "Therefore thus saith the Lord God; Because ye multiplied more than the nations that are round about you, and have not walked in my statutes, neither have kept my judgments, neither have done according to the judgments of the nations that are round about you;", "web": "Therefore thus says the Lord Yahweh: Because you are turbulent more than the nations that are around you, and have not walked in my statutes, neither have kept my ordinances, neither have done after the ordinances of the nations that are around you;", "bsb": "Therefore this is what the Lord GOD says: ‘You have been more insubordinate than the nations around you; you have not walked in My statutes or kept My ordinances, nor have you even conformed to the ordinances of the nations around you.’", "asv": "Therefore thus saith the Lord Jehovah: Because ye are turbulent more than the nations that are round about you, and have not walked in my statutes, neither have kept mine ordinances, neither have done after the ordinances of the nations that are round about you;", "ylt": "Therefore, thus said the Lord Jehovah: Because of your multiplying above the nations that are around you, In My statutes ye have not walked, And My judgments ye have not done, According to the judgments of the nations That are round about you ye have not done.", "dra": "Therefore thus saith the Lord God: Because you have surpassed the Gentiles that are round about you, and have not walked in my commandments, and have not kept my judgments, and have not done according to the judgments of the nations that are round about you:", "bbe": "For this cause the Lord has said: Because you have been more uncontrolled than the nations round about you, and have not been guided by my rules or kept my orders, but have kept the orders of the nations round about you;", "geneva": "Therefore thus saith the Lord God, Because your multitude is greater then the nations that are rounde about you, and ye haue not walked in my statutes, neither haue ye kept my iudgements: no, ye haue not done according to the iudgements of the nations, that are rounde about you,", "wycliffe": "Therfor the Lord God seith these thingis, For ye `han passid hethene men that ben in youre cumpas, and ye yeden not in my comaundementis, and ye diden not my domes, and ye wrouyten not bi the domes of hethene men that ben in youre cumpas;", "rotherham": "Therefore, Thus saith My Lord, Yahweh. Because ye have become more rebellious than the nations who are round about you, In my statutes, have not walked. And my regulations, have not done, And according to the regulations of the nations which are round about you, have not done:", "darby": "Therefore thus saith the Lord Jehovah: Because ye have been turbulent more than the nations that are round about you, [and] have not walked in my statutes, neither have kept mine ordinances, nor [even] have done according to the ordinances of the nations that are round about you;", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because ye have outdone the nations that are round about you, in that ye have not walked in My statutes, neither have kept Mine ordinances, neither have done after the ordinances of the nations that are round about you;", "acv": "Therefore thus says the lord Jehovah: Because ye are more disorderly than the nations that are round about you, and have not walked in my statutes, nor have kept my ordinances, no, ye have not even done according to the ordinances of the nations that are round about you,", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because ye have been rebellious more than the nations that are round about you, and have not walked in my statutes, nor kept my ordinances, but have done according to the ordinances of the nations which are round about you,", "webster": "Therefore thus saith the Lord GOD; Because ye multiplied more than the nations that [are] around you, [and] have not walked in my statutes, neither have kept my judgments, neither have done according to the judgments of the nations that [are] around you:", "vulgate": "idcirco haec dicit Dominus Deus quia superastis gentes quae in circuitu vestro sunt in praeceptis meis non ambulastis et iudicia mea non fecistis et iuxta iudicia gentium quae in circuitu vestro sunt non estis operati;", "brenton": "Therefore thus saith the Lord, Because your occasion for sin has been taken from the nations round about you, and ye have not walked in my statutes, nor kept mine ordinances, nay, ye have not even done according to the ordinances of the nations round about you; therefore thus saith the Lord;"}}, {"v": 8, "ref": "5:8", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֥י עָלַ֖יִ/ךְ גַּם אָ֑נִי וְ/עָשִׂ֧יתִי בְ/תוֹכֵ֛/ךְ מִשְׁפָּטִ֖ים לְ/עֵינֵ֥י הַ/גּוֹיִֽם", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I, even I, am against thee, and will execute judgments in the midst of thee in the sight of the nations.", "web": "therefore thus says the Lord Yahweh: Behold, I, even I, am against you; and I will execute judgments in your midst in the sight of the nations.", "bsb": "Therefore this is what the Lord GOD says: ‘Behold, I Myself am against you, Jerusalem, and I will execute judgments among you in the sight of the nations.", "asv": "therefore thus saith the Lord Jehovah: Behold, I, even I, am against thee; and I will execute judgments in the midst of thee in the sight of the nations.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am against thee, even I, And I have done in thy midst judgments, Before the eyes of the nations.", "dra": "Therefore thus saith the Lord God: Behold I come against thee, and I myself will execute judgments in the midst of thee in the sight of the Gentiles.", "bbe": "For this cause the Lord has said: See, I, even I, am against you; and I will be judging among you before the eyes of the nations.", "geneva": "Therefore thus saith the Lord God, Beholde, I, euen I come against thee, and will execute iudgement in the middes of thee, euen in the sight of the nations.", "wycliffe": "therfor the Lord God seith these thingis, Lo! Y to thee, and Y my silf schal make domes in the myddis of thee, bifor the iyen of hethene men; and Y schal do thingis in thee,", "rotherham": "Therefore, Thus, saith My Lord Yahweh, Lo! I am against thee, even I, Therefore will I, execute in thy midst, judgments, in the eyes of the nations;", "darby": "therefore thus saith the Lord Jehovah: Behold, I, even I, am against thee, and will execute judgments in the midst of thee in the sight of the nations;", "twenty": "", "jps": "therefore thus saith the L-rd GOD: Behold, I, even I, am against thee, and I will execute judgments in the midst of thee in the sight of the nations.", "acv": "therefore thus says the lord Jehovah: Behold, I, even I, am against thee, and I will execute judgments in the midst of thee in the sight of the nations.", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: Behold I, even I, am against thee, and will execute judgments against thee in the sight of the nations.", "webster": "Therefore thus saith the Lord GOD; Behold, I, even I, [am] against thee, and will execute judgments in the midst of thee in the sight of the nations.", "vulgate": "ideo haec dicit Dominus Deus ecce ego ad te et ipse ego faciam in medio tui iudicia in oculis gentium;", "brenton": "Behold, I am against thee, and I will execute judgment in the midst of thee in the sight of the nations."}}, {"v": 9, "ref": "5:9", "o": "וְ/עָשִׂ֣יתִי בָ֗/ךְ אֵ֚ת אֲשֶׁ֣ר לֹֽא עָשִׂ֔יתִי וְ/אֵ֛ת אֲשֶֽׁר לֹֽא אֶעֱשֶׂ֥ה כָמֹ֖/הוּ ע֑וֹד יַ֖עַן כָּל תּוֹעֲבֹתָֽיִ/ךְ", "en": {"kjv": "And I will do in thee that which I have not done, and whereunto I will not do any more the like, because of all thine abominations.", "web": "I will do in you that which I have not done, and which I will not do any more the like, because of all your abominations.", "bsb": "Because of all your abominations, I will do to you what I have never done before and will never do again.", "asv": "And I will do in thee that which I have not done, and whereunto I will not do any more the like, because of all thine abominations.", "ylt": "And I have done in thee that which I have not done, And that which I do not its like again, Because of all thine abominations.", "dra": "And I will do in thee that which I have not done: and the like to which I will do no more, because of all thy abominations.", "bbe": "And I will do in you what I have not done and will not do again, because of all your disgusting ways.", "geneva": "And I will doe in thee, that I neuer did before, neither will do any more the like, because of all thine abominations.", "wycliffe": "whiche Y dide not, and to whiche Y schal no more make lijk thingis, for alle thin abhomynaciouns.", "rotherham": "Yea I will execute upon thee that which I have not executed, And like unto which I will not execute again,- Because of all thine abominations.", "darby": "and I will do in thee that which I have not done, and whereunto I will not do any more the like, because of all thine abominations.", "twenty": "", "jps": "And I will do in thee that which I have not done, and whereunto I will not do any more the like, because of all thine abominations.", "acv": "And I will do in thee that which I have not done, and of which I will not do any more the like, because of all thine abominations.", "anderson": "", "haweis": "", "noyes": "I will do to thee that which I have not yet done, and the like of which I shall not do again, because of all thine iniquities.", "webster": "And I will do in thee that which I have not done, and the like to which I will not do any more, because of all thy abominations.", "vulgate": "et faciam in te quae non feci et quibus similia ultra non faciam propter omnes abominationes tuas;", "brenton": "And I will do in thee things which I have not done, and the like of which I will not do again, for all thine abominations."}}, {"v": 10, "ref": "5:10", "o": "לָ/כֵ֗ן אָב֞וֹת יֹאכְל֤וּ בָנִים֙ בְּ/תוֹכֵ֔/ךְ וּ/בָנִ֖ים יֹאכְל֣וּ אֲבוֹתָ֑/ם וְ/עָשִׂ֤יתִי בָ/ךְ֙ שְׁפָטִ֔ים וְ/זֵרִיתִ֥י אֶת כָּל שְׁאֵרִיתֵ֖/ךְ לְ/כָל רֽוּחַ", "en": {"kjv": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and the whole remnant of thee will I scatter into all the winds.", "web": "Therefore the fathers shall eat the sons in your midst, and the sons shall eat their fathers; and I will execute judgments on you; and the whole remnant of you will I scatter to all the winds.", "bsb": "As a result, fathers among you will eat their sons, and sons will eat their fathers. I will execute judgments against you and scatter all your remnant to every wind.’", "asv": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments on thee; and the whole remnant of thee will I scatter unto all the winds.", "ylt": "Therefore fathers do eat sons in thy midst, And sons eat their fathers, And I have done in thee judgments, And have scattered all thy remnant to every wind.", "dra": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers: and I will execute judgments in thee, and I will scatter thy whole remnant into every wind.", "bbe": "For this cause fathers will take their sons for food among you, and sons will make a meal of their fathers; and I will be judge among you, and all the rest of you I will send away to every wind.", "geneva": "For in the middes of thee, the fathers shall eate their sonnes, and the sonnes shall eate their fathers, and I will execute iudgement in thee, and the whole remnant of thee will I scatter into all the windes.", "wycliffe": "Therfor fadris schulen ete sones in the myddis of thee, and sones schulen ete her fadris; and Y schal make domes in thee, and Y schal wyndewe alle thin remenauntis in to ech wynd.", "rotherham": "Therefore, fathers will eat sons in thy midst, And sons will eat fathers,— And I will execute upon thee judgments, And will scatter the whole remnant of thee, to every wind.", "darby": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and the whole remnant of thee will I scatter to all the winds.", "twenty": "", "jps": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and the whole remnant of thee will I scatter unto all the winds.", "acv": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers. And I will execute judgments on thee, and I will scatter to all the winds the whole remnant of thee.", "anderson": "", "haweis": "", "noyes": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and I will scatter the whole remnant of thee to all the winds.", "webster": "Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and the whole remnant of thee will I scatter into all the winds.", "vulgate": "ideo patres comedent filios in medio tui et filii comedent patres suos et faciam in te iudicia et ventilabo universas reliquias tuas in omnem ventum;", "brenton": "Therefore the fathers shall eat their children in the midst of thee, and children shall eat their fathers; and I will execute judgments in thee, and I will scatter all that are left of thee to every wind."}}, {"v": 11, "ref": "5:11", "o": "לָ/כֵ֣ן חַי אָ֗נִי נְאֻם֮ אֲדֹנָ֣/י יְהוִה֒ אִם לֹ֗א יַ֚עַן אֶת מִקְדָּשִׁ֣/י טִמֵּ֔את בְּ/כָל שִׁקּוּצַ֖יִ/ךְ וּ/בְ/כָל תּוֹעֲבֹתָ֑יִ/ךְ וְ/גַם אֲנִ֤י אֶגְרַע֙ וְ/לֹא תָח֣וֹס עֵינִ֔/י וְ/גַם אֲנִ֖י לֹ֥א אֶחְמֽוֹל", "en": {"kjv": "Wherefore, as I live, saith the Lord God; Surely, because thou hast defiled my sanctuary with all thy detestable things, and with all thine abominations, therefore will I also diminish thee; neither shall mine eye spare, neither will I have any pity.", "web": "Therefore as I live, says the Lord Yahweh, surely, because you have defiled my sanctuary with all your detestable things, and with all your abominations, therefore will I also diminish you; neither shall my eye spare, and I also will have no pity.", "bsb": "Therefore as surely as I live, declares the Lord GOD, because you have defiled My sanctuary with all your detestable idols and abominations, I Myself will withdraw My favor; I will not look upon you with pity, nor will I spare you.", "asv": "Wherefore, as I live, saith the Lord Jehovah, surely, because thou hast defiled my sanctuary with all thy detestable things, and with all thine abominations, therefore will I also diminish thee; neither shall mine eye spare, and I also will have no pity.", "ylt": "Therefore, I live--an affirmation of the Lord Jehovah: Because My sanctuary thou hast defiled, With all thy detestable things, And with all thine abominations, Mine eye pitieth not, and I also spare not. Do not even I also diminish?", "dra": "Therefore as I live, saith the Lord God: Because thou hast violated my sanctuary with all thy offences, and with all thy abominations: I will also break thee in pieces, and my eye shall not spare, and I will not have any pity.", "bbe": "For this cause, by my life, says the Lord, because you have made my holy place unclean with all your hated things and all your disgusting ways, you will become disgusting to me; my eye will have no mercy and I will have no pity.", "geneva": "Wherefore, as I liue, saith the Lord God, Surely because thou hast defiled my Sanctuarie with all thy filthinesse, and with all thine abominations, therefore will I also destroy thee, neither shall mine eye spare thee, neither will I haue any pitie.", "wycliffe": "Therfor Y lyue, seith the Lord God, no but for that that thou defoulidist myn hooli thing in alle thin offenciouns, and in alle thin abhomynaciouns; and Y schal breke, and myn iye schal not spare, and Y schal not do merci.", "rotherham": "Therefore as I live, Declareth My Lord Yahweh,— Surely because my sanctuary, thou hast defiled, with all thy detestable things, and with all thine abominations Even I also, will cut off, and mine eye, shall not spare, Yea even I will not pity.", "darby": "Wherefore, [as] I live, saith the Lord Jehovah, verily because thou hast defiled my sanctuary with all thy detestable things, and with all thine abominations, therefore will I also withdraw mine eye, and it shall not spare, nor will I have any pity.", "twenty": "", "jps": "Wherefore, as I live, saith the L-rd GOD, surely, because thou hast defiled My sanctuary with all thy detestable things, and with all thine abominations, therefore will I also diminish thee; neither shall Mine eye spare, and I also will have no pity.", "acv": "Therefore, as I live, says the lord Jehovah, surely, because thou have defiled my sanctuary with all thy detestable things, and with all thine abominations, therefore I also will diminish thee, nor shall my eye spare. And I also will have no pity.", "anderson": "", "haweis": "", "noyes": "Therefore, as I live, saith the Lord Jehovah, because thou hast polluted my sanctuary with all thy detestable things, and with all thine abominations, therefore will I also withdraw mine eye from thee; neither will I spare, neither will I have any pity.", "webster": "Wherefore, [as] I live, saith the Lord GOD; Surely, because thou hast defiled my sanctuary with all thy detestable things, and with all thy abominations, therefore I will also diminish [thee]; neither shall my eye spare, neither will I have any pity.", "vulgate": "idcirco vivo ego dicit Dominus Deus nisi pro eo quod sanctum meum violasti in omnibus offensionibus tuis et in omnibus abominationibus tuis ego quoque confringam et non parcet oculus meus et non miserebor;", "brenton": "Therefore, as I live, saith the Lord; surely, because thou hast defiled my holy things with all thine abominations, I also will reject thee; mine eye shall not spare, and I will have no mercy."}}, {"v": 12, "ref": "5:12", "o": "שְׁלִשִׁתֵ֞/יךְ בַּ/דֶּ֣בֶר יָמ֗וּתוּ וּ/בָֽ/רָעָב֙ יִכְל֣וּ בְ/תוֹכֵ֔/ךְ וְ/הַ֨/שְּׁלִשִׁ֔ית בַּ/חֶ֖רֶב יִפְּל֣וּ סְבִיבוֹתָ֑יִ/ךְ וְ/הַ/שְּׁלִישִׁית֙ לְ/כָל ר֣וּחַ אֱזָרֶ֔ה וְ/חֶ֖רֶב אָרִ֥יק אַחֲרֵי/הֶֽם", "en": {"kjv": "A third part of thee shall die with the pestilence, and with famine shall they be consumed in the midst of thee: and a third part shall fall by the sword round about thee; and I will scatter a third part into all the winds, and I will draw out a sword after them.", "web": "A third part of you shall die with the pestilence, and with famine shall they be consumed in your midst; and a third part shall fall by the sword around you; and a third part I will scatter to all the winds, and will draw out a sword after them.", "bsb": "A third of your people will die by plague or be consumed by famine within you, a third will fall by the sword outside your walls, and a third I will scatter to every wind and unleash a sword behind them.", "asv": "A third part of thee shall die with the pestilence, and with famine shall they be consumed in the midst of thee; and a third part shall fall by the sword round about thee; and a third part I will scatter unto all the winds, and will draw out a sword after them.", "ylt": "Thy third part--by pestilence they die, And by famine are consumed in thy midst, And the third part, by sword they fall round about thee, And the third part, to every wind I scatter, And a sword I draw out after them.", "dra": "A third part of thee shall die with the pestilence, and shall be consumed with famine in the midst of thee: and a third part of thee shall fall by the sword round about thee: and a third part of thee will I scatter into every wind, and I will draw out a sword after them.", "bbe": "A third of you will come to death from disease, wasting away among you through need of food; a third will be put to the sword round about you; and a third I will send away to every wind, letting loose a sword after them.", "geneva": "The third part of thee shall die with the pestilence, and with famine shall they bee consumed in the middes of thee: and another third part shall fall by the sword round about thee: and I will scatter the last third part into all windes, and I will drawe out a sword after them.", "wycliffe": "The thridde part of thee schal die bi pestilence, and schal be wastid bi hungur in the middis of thee; and the thridde part of thee schal falle doun bi swerd in thi cumpas; forsothe Y schal scatere thi thridde part in to ech wynd, and Y schal drawe out a swerd after hem.", "rotherham": "The third part of thee by pestilence, shall die, and by famine, be consumed in thy midst And the third part by the sword, shall fall round about thee,- And the third part to every wind, will I scatter, and a sword, will I make bare after them.", "darby": "A third part of thee shall die by the pestilence, and shall be consumed by the famine in the midst of thee; and a third part shall fall by the sword round about thee; and I will scatter a third part to all the winds, and I will draw out a sword after them.", "twenty": "", "jps": "A third part of thee shall die with the pestilence, and with famine shall they be consumed in the midst of thee; and a third part shall fall by the sword round about thee; and a third part I will scatter unto all the winds, and will draw out a sword after them.", "acv": "A third part of thee shall die with the pestilence, and they shall be consumed with famine in the midst of thee, and a third part shall fall by the sword round about thee, and a third part I will scatter to all the winds, and will draw out a sword after them.", "anderson": "", "haweis": "", "noyes": "A third part of thee shall die by the pestilence, or be consumed with hunger in the midst of thee; and a third part shall die by the sword round about thee; and a third part will I scatter to all the winds, and I will draw out a sword after them.", "webster": "A third part of thee shall die with the pestilence, and with famine shall they be consumed in the midst of thee: and a third part shall fall by the sword around thee; and I will scatter a third part into all the winds, and I will draw out a sword after them.", "vulgate": "tertia tui pars peste morietur et fame consumetur in medio tui et tertia tui pars gladio cadet in circuitu tuo tertiam vero partem tuam in omnem ventum dispergam et gladium evaginabo post eos;", "brenton": "A fourth part of thee shall be cut off by pestilence, and a fourth part of thee shall be consumed in the midst of thee with famine: and as for another fourth part of thee, I will scatter them to every wind; and a fourth part of thee shall fall by sword round about thee, and I will draw out a sword after them."}}, {"v": 13, "ref": "5:13", "o": "וְ/כָלָ֣ה אַפִּ֗/י וַ/הֲנִחוֹתִ֧י חֲמָתִ֛/י בָּ֖/ם וְ/הִנֶּחָ֑מְתִּי וְֽ/יָדְע֞וּ כִּי אֲנִ֣י יְהוָ֗ה דִּבַּ֨רְתִּי֙ בְּ/קִנְאָתִ֔/י בְּ/כַלּוֹתִ֥/י חֲמָתִ֖/י בָּֽ/ם", "en": {"kjv": "Thus shall mine anger be accomplished, and I will cause my fury to rest upon them, and I will be comforted: and they shall know that I the Lord have spoken it in my zeal, when I have accomplished my fury in them.", "web": "Thus shall my anger be accomplished, and I will cause my wrath toward them to rest, and I shall be comforted; and they shall know that I, Yahweh, have spoken in my zeal, when I have accomplished my wrath on them.", "bsb": "And when My anger is spent and I have vented My wrath against them, I will be appeased. And when I have spent My wrath on them, they will know that I, the LORD, in My zeal have spoken.", "asv": "Thus shall mine anger be accomplished, and I will cause my wrath toward them to rest, and I shall be comforted: and they shall know that I, Jehovah, have spoken in my zeal, when I have accomplished my wrath upon them.", "ylt": "And completed hath been Mine anger, And I have caused My fury to rest on them, And I have been comforted, And they have known that I, Jehovah, have spoken in My zeal, In My completing My fury on them.", "dra": "And I will accomplish my fury, and will cause my indignation to rest upon them, and I will be comforted: and they shall know that I the Lord have spoken it in my zeal, when I shall have accomplished my indignation in them.", "bbe": "So my wrath will be complete and my passion will come to rest on them; and they will be certain that I the Lord have given the word of decision, when my wrath against them is complete.", "geneva": "Thus shall mine anger bee accomplished, and I will cause my wrath to cease in them, and I will be comforted: and they shall knowe, that I the Lord haue spoke it in my zeale, when I haue accomplished my wrath in them.", "wycliffe": "And Y schal fille my stronge veniaunce, and Y schal make myn indignacioun to reste in hem, and Y schal be coumfortid. And thei schulen wite, that Y the Lord spak in my feruent loue, whanne Y schal fille al myn indignacioun in hem.", "rotherham": "So shall mine anger have an end, And I will cause mine indignation, to find rest, upon them, and will console myself,- And they shall know that, I, Yahweh, have spoken in my jealousy, when mine indignation hath come to an end, upon them.", "darby": "And mine anger shall be accomplished, and I will satisfy my fury upon them, and I will comfort myself; and they shall know that I Jehovah have spoken in my jealousy, when I have accomplished my fury upon them.", "twenty": "", "jps": "Thus shall Mine anger spend itself, and I will satisfy My fury upon them, and I will be eased; and they shall know that I HaShem have spoken in My zeal, when I have spent My fury upon them.", "acv": "Thus my anger shall be accomplished, and I will cause my wrath toward them to rest, and I shall be comforted. And they shall know that I, Jehovah, have spoken in my zeal, when I have accomplished my wrath upon them.", "anderson": "", "haweis": "", "noyes": "Thus shall mine anger be accomplished, and I will satiate my fury upon them, and receive satisfaction; and they shall know that I, Jehovah, have spoken it in my zeal, when I shall have accomplished my fury upon them.", "webster": "Thus shall my anger be accomplished, and I will cause my fury to rest upon them, and I will be comforted: and they shall know that I the LORD have spoken [it] in my zeal, when I have accomplished my fury in them.", "vulgate": "et conpleam furorem meum et requiescere faciam indignationem meam in eis et consolabor et scient quia ego Dominus locutus sum in zelo meo cum implevero indignationem meam in eis;", "brenton": "And my wrath and mine anger shall be accomplished upon them: and thou shalt know that I the Lord have spoken in my jealousy, when I have accomplished mine anger upon them."}}, {"v": 14, "ref": "5:14", "o": "וְ/אֶתְּנֵ/ךְ֙ לְ/חָרְבָּ֣ה וּ/לְ/חֶרְפָּ֔ה בַּ/גּוֹיִ֖ם אֲשֶׁ֣ר סְבִיבוֹתָ֑יִ/ךְ לְ/עֵינֵ֖י כָּל עוֹבֵֽר", "en": {"kjv": "Moreover I will make thee waste, and a reproach among the nations that are round about thee, in the sight of all that pass by.", "web": "Moreover I will make you a desolation and a reproach among the nations that are around you, in the sight of all that pass by.", "bsb": "I will make you a ruin and a disgrace among the nations around you, in the sight of all who pass by.", "asv": "Moreover I will make thee a desolation and a reproach among the nations that are round about thee, in the sight of all that pass by.", "ylt": "And I give thee for a waste, And for a reproach among nations that are round about thee, Before the eyes of every passer by.", "dra": "And I will make thee desolate, and a reproach among the nations that are round about thee, in the sight of every one that passeth by.", "bbe": "And I will make you a waste and a name of shame among the nations round about you, in the eyes of everyone who goes by.", "geneva": "Moreouer, I will make thee waste, and abhorred among the nations, that are round about thee, and in the sight of all that passe by.", "wycliffe": "And Y schal yyue thee in to desert, in to schenschipe to hethene men that ben in thi cumpas, in the siyt of ech that passith forth.", "rotherham": "And I will deliver thee up to desolation and reproach, among the nations that are round about thee,—in the eyes of every passer-by.", "darby": "And I will make thee a waste and a reproach among the nations that are round about thee, in the sight of all that pass by.", "twenty": "", "jps": "Moreover I will make thee an amazement and a reproach, among the nations that are round about thee, in the sight of all that pass by.", "acv": "Moreover I will make thee a desolation and a reproach among the nations that are round about thee, in the sight of all who pass by.", "anderson": "", "haweis": "", "noyes": "Moreover, I will make thee a waste, and a reproach among the nations that are round about thee, in the sight of all that pass by.", "webster": "Moreover I will make thee waste, and a reproach among the nations that [are] around thee, in the sight of all that pass by.", "vulgate": "et dabo te in desertum et in obprobrium in gentibus quae in circuitu tuo sunt in conspectu omnis praetereuntis;", "brenton": "And I will make thee desolate, and thy daughters round about thee, in the sight of every one that passes through."}}, {"v": 15, "ref": "5:15", "o": "וְֽ/הָ֨יְתָ֜ה חֶרְפָּ֤ה וּ/גְדוּפָה֙ מוּסָ֣ר וּ/מְשַׁמָּ֔ה לַ/גּוֹיִ֖ם אֲשֶׁ֣ר סְבִיבוֹתָ֑יִ/ךְ בַּ/עֲשׂוֹתִ/י֩ בָ֨/ךְ שְׁפָטִ֜ים בְּ/אַ֤ף וּ/בְ/חֵמָה֙ וּ/בְ/תֹכְח֣וֹת חֵמָ֔ה אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "So it shall be a reproach and a taunt, an instruction and an astonishment unto the nations that are round about thee, when I shall execute judgments in thee in anger and in fury and in furious rebukes. I the Lord have spoken it.", "web": "So it shall be a reproach and a taunt, an instruction and an astonishment, to the nations that are around you, when I shall execute judgments on you in anger and in wrath, and in wrathful rebukes; (I, Yahweh, have spoken it;)", "bsb": "So you will be a reproach and a taunt, a warning and a horror to the nations around you, when I execute judgments against you in anger, wrath, and raging fury. I, the LORD, have spoken.", "asv": "So it shall be a reproach and a taunt, an instruction and an astonishment, unto the nations that are round about thee, when I shall execute judgments on thee in anger and in wrath, and in wrathful rebukes (I, Jehovah, have spoken it);", "ylt": "And it hath been a reproach and a reviling, An instruction and an astonishment, To nations that are round about thee, In My doing in thee judgments, In anger and fury, and in furious reproofs, I, Jehovah, have spoken.", "dra": "And thou shalt be a reproach, and a scoff, an example, and an astonishment amongst the nations that are round about thee, when I shall have executed judgments in thee in anger, and in indignation, and in wrathful rebukes.", "bbe": "And you will be a name of shame and a cause of bitter words, an example and a wonder to the nations round about you, when I give effect to my judging among you in wrath and in passion and in burning protests: I the Lord have said it:", "geneva": "So thou shalt bee a reproche and shame, a chastisement and an astonishment vnto the nations, that are rounde about thee, when I shall execute iudgements in thee, in anger and in wrath, and in sharpe rebukes: I the Lord haue spoken it.", "wycliffe": "And thou schalt be schenschipe `and blasfemye, ensaumple and wondryng, among hethene men that ben in thi cumpas, whanne Y schal make domes in thee, in strong veniaunce, and indignacioun, and in blamyngis of ire.", "rotherham": "So shall it become a reproach and an insult a warning and an astonishment, to the nations that are round about thee,—in that I have executed upon thee judgments in anger and in indignation and in rebukes of indignation, I, Yahweh have spoken:", "darby": "And it shall be a reproach, and a taunt, an instruction, and an astonishment unto the nations that are round about thee, when I shall execute judgments upon thee in anger, and in fury, and in furious rebukes: I, Jehovah, have spoken.", "twenty": "", "jps": "So it shall be a reproach and a taunt, an instruction and an astonishment, unto the nations that are round about thee, when I shall execute judgments in thee in anger and in fury, and in furious rebukes; I HaShem have spoken it;", "acv": "So it shall be a reproach and a taunt, a lesson and an astonishment, to the nations that are round about thee, when I shall execute judgments on thee in anger and in wrath, and in wrathful rebukes-I, Jehovah, have spoken it-", "anderson": "", "haweis": "", "noyes": "And thou shalt be a reproach, and a reviling, and a warning, and an astonishment to the nations that are round about thee, when I shall execute judgments upon thee in anger, and in fury, and in furious rebukes; —I, Jehovah, have spoken it; —", "webster": "So it shall be a reproach and a taunt, an instruction and an astonishment to the nations that [are] around thee, when I shall execute judgments in thee in anger and in fury and in furious rebukes. I the LORD have spoken [it].", "vulgate": "et eris obprobrium et blasphemia exemplum et stupor in gentibus quae in circuitu tuo sunt cum fecero in te iudicia in furore et in indignatione et in increpationibus irae;", "brenton": "And thou shalt be mourned over and miserable among the nations round about thee, when I have executed judgments in thee in the vengeance of my wrath. I the Lord have spoken."}}, {"v": 16, "ref": "5:16", "o": "בְּֽ/שַׁלְּחִ֡/י אֶת חִצֵּי֩ הָ/רָעָ֨ב הָ/רָעִ֤ים בָּ/הֶם֙ אֲשֶׁ֣ר הָי֣וּ לְ/מַשְׁחִ֔ית אֲשֶׁר אֲשַׁלַּ֥ח אוֹתָ֖/ם לְ/שַֽׁחֶתְ/כֶ֑ם וְ/רָעָב֙ אֹסֵ֣ף עֲלֵי/כֶ֔ם וְ/שָׁבַרְתִּ֥י לָ/כֶ֖ם מַטֵּה לָֽחֶם", "en": {"kjv": "When I shall send upon them the evil arrows of famine, which shall be for their destruction, and which I will send to destroy you: and I will increase the famine upon you, and will break your staff of bread:", "web": "when I shall send on them the evil arrows of famine, that are for destruction, which I will send to destroy you: and I will increase the famine on you, and will break your staff of bread;", "bsb": "When I shower you with the deadly arrows of famine and destruction that I will send to destroy you, I will intensify the famine against you and cut off your supply of food.", "asv": "when I shall send upon them the evil arrows of famine, that are for destruction, which I will send to destroy you. And I will increase the famine upon you, and will break your staff of bread;", "ylt": "In My sending the evil arrows of famine among them, That have been for destruction, That I send to destroy you, And famine I am adding upon you, And I have broken to you the staff of bread.", "dra": "I the Lord have spoken it: When I shall send upon them the grievous arrows of famine, which shall bring death, and which I will send to destroy you: and I will gather together famine against you: and I will break among you the staff of bread.", "bbe": "When I send on you the evil arrows of disease, causing destruction, which I will send to put an end to you; and, further, I will take away your necessary food.", "geneva": "When I shall sende vpon them the euill arrowes of famine, which shalbe for their destruction, and which I will sende to destroy you: and I will encrease the famine vpon you, and wil breake your staffe of bread.", "wycliffe": "Y the Lord haue spoke, whanne Y schal sende in to hem the worste arowis of hungur, that schulen bere deth; and whiche Y schal sende, that Y leese you. And Y schal gadere hungur on you, and Y schal al to-breke in you the sadnesse of breed.", "rotherham": "In that I have sent the malignant arrows of famine among them which were for destruction, which I will send to destroy you,—and famine, will I increase upon you, and will break for you the staff of bread.", "darby": "When I send upon them the evil arrows of famine, that are for [their] destruction, which I send to destroy you, then will I increase the famine upon you, and will break your staff of bread.", "twenty": "", "jps": "when I shall send upon them the evil arrows of famine, that are for destruction, which I will send to destroy you; and I will increase the famine upon you, and will break your staff of bread;", "acv": "when I shall send upon them the evil arrows of famine that are for destruction, which I will send to destroy you. And I will increase the famine upon you, and will break your staff of bread.", "anderson": "", "haweis": "", "noyes": "when I shall send upon you the evil arrows of famine which bring destruction, which I send to destroy you, and increase the famine upon you, and break your staff of bread.", "webster": "When I shall send upon them the evil arrows of famine, which shall be for [their] destruction, [and] which I will send to destroy you: and I will increase the famine upon you, and will break your staff of bread:", "vulgate": "ego Dominus locutus sum quando misero sagittas famis pessimas in eos quae erunt mortiferae et quas mittam ut disperdam vos et famem congregabo super vos et conteram vobis baculum panis;", "brenton": "And when I have sent against them shafts of famine, then they shall be consumed, and I will break the strength of thy bread."}}, {"v": 17, "ref": "5:17", "o": "וְ/שִׁלַּחְתִּ֣י עֲ֠לֵי/כֶם רָעָ֞ב וְ/חַיָּ֤ה רָעָה֙ וְ/שִׁכְּלֻ֔/ךְ וְ/דֶ֥בֶר וָ/דָ֖ם יַעֲבָר בָּ֑/ךְ וְ/חֶ֨רֶב֙ אָבִ֣יא עָלַ֔יִ/ךְ אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "So will I send upon you famine and evil beasts, and they shall bereave thee; and pestilence and blood shall pass through thee; and I will bring the sword upon thee. I the Lord have spoken it.", "web": "and I will send on you famine and evil animals, and they shall bereave you; and pestilence and blood shall pass through you; and I will bring the sword on you: I, Yahweh, have spoken it.", "bsb": "I will send famine and wild beasts against you, and they will leave you childless. Plague and bloodshed will sweep through you, and I will bring a sword against you. I, the LORD, have spoken.”", "asv": "and I will send upon you famine and evil beasts, and they shall bereave thee; and pestilence and blood shall pass through thee; and I will bring the sword upon thee: I, Jehovah, have spoken it.", "ylt": "And I have sent on you famine and evil beasts, And they have bereaved thee, And pestilence and blood pass over on thee, And a sword I do bring in against thee, I, Jehovah, have spoken!'", "dra": "And I will send in upon you famine, and evil beasts unto utter destruction: and pestilence, and blood shall pass through thee, and I will bring in the sword upon thee. I the Lord have spoken it.", "bbe": "And I will send on you need of food and evil beasts, and they will be a cause of loss to you; and disease and violent death will go through you; and I will send the sword on you: I the Lord have said it.", "geneva": "So will I send vpon you famine, and euill beastes, and they shall spoyle thee, and pestilence and blood shall passe through thee, and I will bring the sworde vpon thee: I the Lord haue spoken it.", "wycliffe": "And Y schal sende in to you hungur, and worste beestis, til to the deth; and pestilence and blood schulen passe bi thee, and Y schal bringe in swerd on thee; Y the Lord spak.", "rotherham": "So will I send upon you famine and mischievous beast and they shall bereave thee,—and pestilence and blood, shall pass through thee,—and a sword, will I bring in upon thee, I Yahweh, have spoken.", "darby": "And I will send upon you famine and evil beasts, which shall bereave thee of children; and pestilence and blood shall pass through thee; and I will bring the sword upon thee: I, Jehovah, have spoken.", "twenty": "", "jps": "and I will send upon you famine and evil beasts, and they shall bereave thee; and pestilence and blood shall pass through thee; and I will bring the sword upon thee. I HaShem have spoken it.'", "acv": "And I will send upon you famine and evil beasts, and they shall bereave thee. And pestilence and blood shall pass through thee. And I will bring the sword upon thee. I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "And I will send upon you famine, and evil beasts, which shall make thee childless; and pestilence and blood shall pass through thee; and the sword will I bring upon thee. I, Jehovah, have spoken it.", "webster": "So will I send upon you famine and evil beasts, and they shall bereave thee; and pestilence and blood shall pass through thee; and I will bring the sword upon thee. I the LORD have spoken [it].", "vulgate": "et inmittam in vos famem et bestias pessimas usque ad internicionem et pestilentia et sanguis transibunt per te et gladium inducam super te ego Dominus locutus sum;", "brenton": "So I will send forth against thee famine and evil beasts, and I will take vengeance upon thee; and pestilence and blood shall pass through upon thee; and I will bring a sword upon thee round about. I the Lord have spoken."}}]}, {"c": 6, "verses": [{"v": 1, "ref": "6:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Again the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh. unto me saying,", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "6:2", "o": "בֶּן אָדָ֕ם שִׂ֥ים פָּנֶ֖י/ךָ אֶל הָרֵ֣י יִשְׂרָאֵ֑ל וְ/הִנָּבֵ֖א אֲלֵי/הֶֽם", "en": {"kjv": "Son of man, set thy face toward the mountains of Israel, and prophesy against them,", "web": "Son of man, set your face toward the mountains of Israel, and prophesy to them,", "bsb": "“Son of man, set your face against the mountains of Israel and prophesy against them.", "asv": "Son of man, set thy face toward the mountains of Israel, and prophesy unto them,", "ylt": "`Son of man, set thy face unto mountains of Israel, and prophesy concerning them:", "dra": "Son of man set thy face towards the mountains of Israel, and prophesy against them.", "bbe": "Son of man, let your face be turned to the mountains of Israel, and be a prophet to them, and say,", "geneva": "Sonne of man, Set thy face towardes the mountaines of Israel, and prophecie against them,", "wycliffe": "and he seide, Thou, sone of man, sette thi face to the hillis of Israel; and thou schalt profesie to tho hillis, and schalt seie,", "rotherham": "Son of man, Set thy face against the mountains of Israel,— and prophesy unto them;", "darby": "Son of man, set thy face toward the mountains of Israel, and prophesy against them,", "twenty": "", "jps": "'Son of man, set thy face toward the mountains of Israel, and prophesy against them,", "acv": "Son of man, set thy face toward the mountains of Israel, and prophesy to them,", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against the mountains of Israel, and prophesy against them!", "webster": "Son of man, set thy face towards the mountains of Israel, and prophesy against them,", "vulgate": "fili hominis pone faciem tuam ad montes Israhel et prophetabis ad eos;", "brenton": "Son of man, set thy face against the mountains of Israel, and prophesy against them;"}}, {"v": 3, "ref": "6:3", "o": "וְ/אָ֣מַרְתָּ֔ הָרֵי֙ יִשְׂרָאֵ֔ל שִׁמְע֖וּ דְּבַר אֲדֹנָ֣/י יְהוִ֑ה כֹּה אָמַ֣ר אֲדֹנָ֣/י יְ֠הוִה לֶ/הָרִ֨ים וְ/לַ/גְּבָע֜וֹת לָ/אֲפִיקִ֣ים ו/ל/גאית וְ/לַ/גֵּאָי֗וֹת הִנְ/נִ֨י אֲנִ֜י מֵבִ֤יא עֲלֵי/כֶם֙ חֶ֔רֶב וְ/אִבַּדְתִּ֖י בָּמֽוֹתֵי/כֶֽם", "en": {"kjv": "And say, Ye mountains of Israel, hear the word of the Lord God; Thus saith the Lord God to the mountains, and to the hills, to the rivers, and to the valleys; Behold, I, even I, will bring a sword upon you, and I will destroy your high places.", "web": "and say, You mountains of Israel, hear the word of the Lord Yahweh: Thus says the Lord Yahweh to the mountains and to the hills, to the watercourses and to the valleys: Behold, I, even I, will bring a sword on you, and I will destroy your high places.", "bsb": "You are to say: ‘O mountains of Israel, hear the word of the Lord GOD! This is what the Lord GOD says to the mountains and hills, to the ravines and valleys: I am about to bring a sword against you, and I will destroy your high places.", "asv": "and say, Ye mountains of Israel, hear the word of the Lord Jehovah: Thus saith the Lord Jehovah to the mountains and to the hills, to the watercourses and to the valleys: Behold, I, even I, will bring a sword upon you, and I will destroy your high places.", "ylt": "And thou hast said: Mountains of Israel, Hear ye a word of the Lord Jehovah: Thus said the Lord Jehovah To the mountains, and to the hills, To the streams, and to the valleys, Lo, I, I am bringing in against you a sword, And I have destroyed your high places.", "dra": "And say: Ye mountains of Israel, hear the word of the Lord God: Thus saith the Lord God to the mountains, and to the hills, and to the rocks, and the valleys: Behold, I will bring upon you the sword, and I will destroy your high places.", "bbe": "You mountains of Israel, give ear to the words of the Lord: this is what the Lord has said to the mountains and the hills, to the waterways and the valleys: See, I, even I, am sending on you a sword for the destruction of your high places.", "geneva": "And say, Ye mountaines of Israel, heare the worde of the Lord God: thus sayth the Lord God to the mountaines and to the hilles, to the riuers and to the valleis, Beholde, I, euen I will bring a sworde vpon you, and I will destroy your hie places:", "wycliffe": "Hillis of Israel, here ye the word of the Lord God. The Lord God seith these thingis to mounteyns, and litil hillis, to roochis of stoon, and to valeis, Lo! Y schal bringe in on you a swerd, and Y schal leese youre hiye thingis.", "rotherham": "and say, Ye mountains of Israel, hear ye the word of My Lord Yahweh,— Thus saith My Lord, Yahweh- To the mountains and to the hills to the hollows and to the valleys,- Behold me! I, am bringing upon you a sword, And I will destroy your high places;", "darby": "and say, Mountains of Israel, hear the word of the Lord Jehovah: thus saith the Lord Jehovah to the mountains and to the hills, to the water-courses and to the valleys: Behold, I, [even] I, do bring a sword upon you, and will destroy your high places.", "twenty": "", "jps": "and say: Ye mountains of Israel, hear the word of the L-rd GOD: Thus saith the L-rd GOD concerning the mountains and concerning the hills, concerning the ravines and concerning the valleys: Behold, I, even I, will bring a sword upon you, and I will destroy your high places.", "acv": "and say, Ye mountains of Israel, hear the word of lord Jehovah. Thus says the lord Jehovah to the mountains and to the hills, to the watercourses and to the valleys: Behold, I, even I, will bring a sword upon you, and I will destroy your high places.", "anderson": "", "haweis": "", "noyes": "And say, Ye mountains of Israel, hear the word of the Lord Jehovah! Thus saith the Lord Jehovah to the mountains and to the hills, to the plains and to the valleys: Behold, I, even I, will bring the sword upon you, and I will destroy your high places;", "webster": "And say, Ye mountains of Israel, hear the word of the Lord GOD: Thus saith the Lord GOD to the mountains, and to the hills, to the rivers, and to the valleys; Behold, I, [even] I, will bring a sword upon you, and I will destroy your high places.", "vulgate": "et dices montes Israhel audite verbum Domini Dei haec dicit Dominus Deus montibus et collibus rupibus et vallibus ecce ego inducam super vos gladium et disperdam excelsa vestra;", "brenton": "and thou shalt say, Ye mountains of Israel, hear the word of the Lord; thus saith the Lord to the mountains, and to the hills, and to the valleys, and to the forests; Behold, I bring a sword upon you, and your high places shall be utterly destroyed."}}, {"v": 4, "ref": "6:4", "o": "וְ/נָשַׁ֨מּוּ֙ מִזְבְּח֣וֹתֵי/כֶ֔ם וְ/נִשְׁבְּר֖וּ חַמָּֽנֵי/כֶ֑ם וְ/הִפַּלְתִּי֙ חַלְלֵי/כֶ֔ם לִ/פְנֵ֖י גִּלּוּלֵי/כֶֽם", "en": {"kjv": "And your altars shall be desolate, and your images shall be broken: and I will cast down your slain men before your idols.", "web": "Your altars shall become desolate, and your incense altars shall be broken; and I will cast down your slain men before your idols.", "bsb": "Your altars will be demolished and your incense altars will be smashed; and I will cast down your slain before your idols.", "asv": "And your altars shall become desolate, and your sun-images shall be broken; and I will cast down your slain men before your idols.", "ylt": "And desolated have been your altars, And broken your images, And I have caused your wounded to fall before your idols,", "dra": "And I will throw down your altars, and your idols shall be broken in pieces: and I will cast down your slain before your idols.", "bbe": "And your altars will be made waste, and your sun-images will be broken: and I will have your dead men placed before your images.", "geneva": "And your altars shalbe desolate, and your images of the sunne shalbe broken: and I will cast downe your slaine men before your idoles.", "wycliffe": "And Y schal distrie youre auteris, and youre symylacris schulen be brokun; and Y schal caste doun youre slayn men bifore youre idols.", "rotherham": "And your altars shall be laid waste, And your sun-pillars shall be broken in pieces,— And I will cause your slain to fall before your manufactured gods;", "darby": "And your altars shall be desolate, and your sun-images shall be broken; and I will cast down your slain [men] before your idols;", "twenty": "", "jps": "And your altars shall become desolate, and your sun-images shall be broken; and I will cast down your slain men before your idols.", "acv": "And your altars shall become desolate, and your sun-images shall be broken, and I will cast down your slain men before your idols.", "anderson": "", "haweis": "", "noyes": "and your altars shall be desolate, and your sun-images shall be broken; and I will cast down your slain before your idols.", "webster": "And your altars shall be desolate, and your images shall be broken: and I will cast down your slain [men] before your idols.", "vulgate": "et demoliar aras vestras et confringentur simulacra vestra et deiciam interfectos vestros ante idola vestra;", "brenton": "And your altars shall be broken to pieces, and your consecrated plats; and I will cast down your slain men before your idols."}}, {"v": 5, "ref": "6:5", "o": "וְ/נָתַתִּ֗י אֶת פִּגְרֵי֙ בְּנֵ֣י יִשְׂרָאֵ֔ל לִ/פְנֵ֖י גִּלּֽוּלֵי/הֶ֑ם וְ/זֵרִיתִי֙ אֶת עַצְמ֣וֹתֵי/כֶ֔ם סְבִיב֖וֹת מִזְבְּחוֹתֵי/כֶֽם", "en": {"kjv": "And I will lay the dead carcases of the children of Israel before their idols; and I will scatter your bones round about your altars.", "web": "I will lay the dead bodies of the children of Israel before their idols; and I will scatter your bones around your altars.", "bsb": "I will lay the corpses of the Israelites before their idols and scatter your bones around your altars.", "asv": "And I will lay the dead bodies of the children of Israel before their idols; and I will scatter your bones round about your altars.", "ylt": "And put the carcases of the sons of Israel before their idols, And scattered your bones round about your altars.", "dra": "And I will lay the dead carcasses of the children of Israel before your idols: and I will scatter your bones round about your altars,", "bbe": "And I will put the dead bodies of the children of Israel in front of their images, sending your bones in all directions about your altars.", "geneva": "And I will lay the dead carkeises of the children of Israel before their idoles, and I will scatter your bones round about your altars.", "wycliffe": "dnA Y schal yyue the deed bodies of the sones of Israel bifor the face of youre symylacris, and Y schal scatere youre boonys", "rotherham": "And I will lay the carcases of the sons of Israel before their manufactured gods,— And will scatter your bones round about your altars.", "darby": "and I will lay the dead bodies of the children of Israel before their idols; and I will scatter your bones round about your altars.", "twenty": "", "jps": "And I will lay the carcasses of the children of Israel before their idols; and I will scatter your bones round about your altars.", "acv": "And I will lay the dead bodies of the sons of Israel before their idols, and I will scatter your bones round about your altars.", "anderson": "", "haweis": "", "noyes": "And I will lay the carcasses of the sons of Israel before their idols; and I will scatter your bones round about your altars.", "webster": "And I will lay the dead carcasses of the children of Israel before their idols; and I will scatter your bones about your altars.", "vulgate": "et dabo cadavera filiorum Israhel ante faciem simulacrorum vestrorum et dispergam ossa vestra circum aras vestras;", "brenton": "And I will scatter your bones round about your altars,"}}, {"v": 6, "ref": "6:6", "o": "בְּ/כֹל֙ מוֹשְׁב֣וֹתֵי/כֶ֔ם הֶ/עָרִ֣ים תֶּחֱרַ֔בְנָה וְ/הַ/בָּמ֖וֹת תִּישָׁ֑מְנָה לְמַעַן֩ יֶחֶרְב֨וּ וְ/יֶאְשְׁמ֜וּ מִזְבְּחֽוֹתֵי/כֶ֗ם וְ/נִשְׁבְּר֤וּ וְ/נִשְׁבְּתוּ֙ גִּלּ֣וּלֵי/כֶ֔ם וְ/נִגְדְּעוּ֙ חַמָּ֣נֵי/כֶ֔ם וְ/נִמְח֖וּ מַעֲשֵׂי/כֶֽם", "en": {"kjv": "In all your dwellingplaces the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your images may be cut down, and your works may be abolished.", "web": "In all your dwelling places the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your incense altars may be cut down, and your works may be abolished.", "bsb": "Wherever you live, the cities will be laid waste and the high places will be demolished, so that your altars will be laid waste and desecrated, your idols smashed and obliterated, your incense altars cut down, and your works blotted out.", "asv": "In all your dwelling-places the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your sun-images may be hewn down, and your works may be abolished.", "ylt": "In all your dwellings the cities are laid waste, And the high places are desolate, So that waste and desolate are your altars, And broken and ceased have your idols, And cut down have been your images, And blotted out have been your works.", "dra": "In all your dwelling places. The cities shall be laid waste, and the high places shall be thrown down, and destroyed, and your altars shall be abolished, and shall be broken in pieces: and your idols shall be no more, and your temples shall be destroyed, and your works shall be defaced.", "bbe": "In all your living-places the towns will become broken walls, and the high places made waste; so that your altars may be broken down and made waste, and your images broken and ended, and so that your sun-images may be cut down and your works rubbed out.", "geneva": "In all your dwelling places the cities shalbe desolate, and the hie places shalbe laide waste, so that your altars shalbe made waste and desolate, and your idoles shalbe broken, and cease, and your images of the sunne shalbe cut in pieces, and your workes shalbe abolished.", "wycliffe": "aboute youre auteris, in alle youre dwellingis. Citees schulen be forsakun, and hiy thingis schulen be distried, and schulen be scaterid; and youre auteris schulen perische, and schulen be brokun. And youre idols schulen ceesse, and youre templis of idols schulen be al to-brokun, and youre werkis schulen be doen awei.", "rotherham": "In all your dwelling-places, The cities, shall be laid waste, and, The high places, shall be made desolate, To the end your altars may be laid waste and become desolate. And your manufactured gods be broken in pieces and cease, And your sun-pillars be cut down, And your handiworks be abolished.", "darby": "In all your dwelling-places the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your sun-images may be cut down, and your works may be abolished.", "twenty": "", "jps": "In all your dwelling-places the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your sun-images may be hewn down, and your works may be blotted out.", "acv": "In all your dwelling places the cities shall be laid waste, and the high places shall be desolate, that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your sun-images may be hewn down, and your works may be abolished.", "anderson": "", "haweis": "", "noyes": "In all places where ye dwell shall the cities be laid waste, and the high places be desolate; that your altars may be laid waste and made desolate, and your idols may be broken, and cease, and your sun-images may be cut down, and your works may be destroyed.", "webster": "In all your dwelling-places the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your images may be cut down, and your works may be abolished.", "vulgate": "in omnibus habitationibus vestris urbes desertae erunt et excelsa demolientur et dissipabuntur et interibunt arae vestrae et confringentur et cessabunt idola vestra et conterentur delubra vestra et delebuntur opera vestra;", "brenton": "and in all your habitations: the cities shall be made desolate, and the high places utterly laid waste; that your altars may be destroyed, and your idols be broken to pieces, and your consecrated plats be abolished."}}, {"v": 7, "ref": "6:7", "o": "וְ/נָפַ֥ל חָלָ֖ל בְּ/תֽוֹכְ/כֶ֑ם וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And the slain shall fall in the midst of you, and ye shall know that I am the Lord.", "web": "The slain shall fall in your midst, and you shall know that I am Yahweh.", "bsb": "The slain will fall among you, and you will know that I am the LORD.", "asv": "And the slain shall fall in the midst of you, and ye shall know that I am Jehovah.", "ylt": "And fallen hath the wounded in your midst, And ye have known that I am Jehovah.", "dra": "And the slain shall fall in the midst of you: and you shall know that I am the Lord.", "bbe": "And the dead will be falling down among you, and you will be certain that I am the Lord.", "geneva": "And the slaine shall fall in the middes of you, and ye shall knowe that I am the Lord.", "wycliffe": "And a slayn man schal falle doun in the myddis of you; and ye schulen wite, that Y am the Lord.", "rotherham": "And the slain shall fall in your midst, So shall ye know that I am Yahweh.", "darby": "And the slain shall fall in the midst of you, and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "And the slain shall fall in the midst of you, and ye shall know that I am HaShem.", "acv": "And the slain shall fall in the midst of you. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And the slain shall fall in the midst of you, that ye may know that I am Jehovah.", "webster": "And the slain shall fall in the midst of you, and ye shall know that I [am] the LORD.", "vulgate": "et cadet interfectus in medio vestri et scietis quoniam ego Dominus;", "brenton": "And slain men shall fall in the midst of you, and ye shall know that I am the Lord."}}, {"v": 8, "ref": "6:8", "o": "וְ/הוֹתַרְתִּ֗י בִּ/הְי֥וֹת לָ/כֶ֛ם פְּלִ֥יטֵי חֶ֖רֶב בַּ/גּוֹיִ֑ם בְּ/הִזָּרֽוֹתֵי/כֶ֖ם בָּ/אֲרָצֽוֹת", "en": {"kjv": "Yet will I leave a remnant, that ye may have some that shall escape the sword among the nations, when ye shall be scattered through the countries.", "web": "Yet will I leave a remnant, in that you shall have some that escape the sword among the nations, when you shall be scattered through the countries.", "bsb": "Yet I will leave a remnant, for some of you will escape the sword when you are scattered among the nations and throughout the lands.", "asv": "Yet will I leave a remnant, in that ye shall have some that escape the sword among the nations, when ye shall be scattered through the countries.", "ylt": "And I have caused some to remain, In their being to you the escaped of the sword among nations, In your being scattered through lands.", "dra": "And I will leave in you some that shall escape the sword among the nations, when I shall have scattered you through the countries.", "bbe": "But still, I will keep a small band safe from the sword among the nations, when you are sent wandering among the countries.", "geneva": "Yet will I leaue a remnant, that you may haue some that shall escape the sword among the nations, when you shalbe scattred through the countreyes.", "wycliffe": "And Y schal leeue in you hem that fledden swerd among hethene men, whanne Y schal scatere you in to londis.", "rotherham": "Yet will I leave a remnant: In that ye shall have such as are escaped of the sword throughout the nations, when ye are scattered throughout the lands.", "darby": "Yet will I leave a remnant, in that ye shall have some escaped from the sword among the nations, when ye shall be scattered through the countries.", "twenty": "", "jps": "Yet will I leave a remnant, in that ye shall have some that escape the sword among the nations, when ye shall be scattered through the countries.", "acv": "Yet I will leave a remnant, in that ye shall have some who escape the sword among the nations, when ye shall be scattered through the countries.", "anderson": "", "haweis": "", "noyes": "Yet will I leave a remnant, that ye may have some that shall have escaped the sword among the nations, when ye shall be scattered through the countries.", "webster": "Yet will I leave a remnant, that ye may have [some] that shall escape the sword among the nations, when ye shall be scattered through the countries.", "vulgate": "et relinquam in vobis eos qui fugerint gladium in gentibus cum dispersero vos in terris;", "brenton": "When there are some of you escaping from the sword among the Gentiles, and when ye are scattered in the countries;"}}, {"v": 9, "ref": "6:9", "o": "וְ/זָכְר֨וּ פְלִֽיטֵי/כֶ֜ם אוֹתִ֗/י בַּ/גּוֹיִם֮ אֲשֶׁ֣ר נִשְׁבּוּ שָׁם֒ אֲשֶׁ֨ר נִשְׁבַּ֜רְתִּי אֶת לִבָּ֣/ם הַ/זּוֹנֶ֗ה אֲשֶׁר סָר֙ מֵֽ/עָלַ֔/י וְ/אֵת֙ עֵֽינֵי/הֶ֔ם הַ/זֹּנ֕וֹת אַחֲרֵ֖י גִּלּֽוּלֵי/הֶ֑ם וְ/נָקֹ֨טּוּ֙ בִּ/פְנֵי/הֶ֔ם אֶל הָֽ/רָעוֹת֙ אֲשֶׁ֣ר עָשׂ֔וּ לְ/כֹ֖ל תּוֹעֲבֹתֵי/הֶֽם", "en": {"kjv": "And they that escape of you shall remember me among the nations whither they shall be carried captives, because I am broken with their whorish heart, which hath departed from me, and with their eyes, which go a whoring after their idols: and they shall lothe themselves for the evils which they have committed in all their abominations.", "web": "Those of you that escape shall remember me among the nations where they shall be carried captive, how that I have been broken with their lewd heart, which has departed from me, and with their eyes, which play the prostitute after their idols: and they shall loathe themselves in their own sight for the evils which they have committed in all their abominations.", "bsb": "Then in the nations to which they have been carried captive, your survivors will remember Me—how I have been grieved by their adulterous hearts that turned away from Me, and by their eyes that lusted after idols. So they will loathe themselves for the evil they have done and for all their abominations.", "asv": "And those of you that escape shall remember me among the nations whither they shall be carried captive, how that I have been broken with their lewd heart, which hath departed from me, and with their eyes, which play the harlot after their idols: and they shall loathe themselves in their own sight for the evils which they have committed in all their abominations.", "ylt": "And remembered Me have your escaped among nations, Whither they have been taken captive, Because I have been broken with their heart that is going a-whoring, That hath turned aside from off Me, And with their eyes they are going a-whoring after their idols, And they have been loathsome in their own faces, For the evils that they have done--all their abominations.", "dra": "And they that are saved of you shall remember me amongst the nations, to which they are carried captives: because I have broken their heart that was faithless, and revolted from me: and their eyes that went a fornicating after their idols: and they shall be displeased with themselves because of the evils which they have committed in all their abominations.", "bbe": "And those of you who are kept safe will have me in mind among the nations where they have been taken away as prisoners, how I sent punishment on their hearts which were untrue to me, and on their eyes which were turned to their false gods: and they will be full of hate for themselves because of the evil things which they have done in all their disgusting ways.", "geneva": "And they that escape of you, shall remember me among the nations, where they shalbe in captiuitie, because I am grieued for their whorish hearts, which haue departed from mee, and for their eyes, which haue gone a whoring after their idoles, and they shalbe displeased in them selues for the euils, which they haue committed in all their abominations.", "wycliffe": "And youre delyuered men schulen haue mynde on me among hethene men, to whiche thei ben led prisoneris; for Y haue al to-broke her herte doynge fornycacioun, and goynge awei fro me, and her iyen doynge fornicacioun aftir her idols. And thei schulen displese hem silf on the yuels, whiche thei diden in alle her abhomynaciouns.", "rotherham": "Then shall they who have escaped of you remember me, among the nations whither they have been carried captive, In that I have broken their adulterous heart, which hath turned aside from me, And their eyes which have adulterously gone after their manufactured gods, So shall they become loathsome in their own sight, for the wicked things which they have done in all their abominations.", "darby": "And they that escape of you shall remember me among the nations whither they have been carried captives, when I shall have broken their whorish heart, which hath departed from me, and their eyes, which go a whoring after their idols; and they shall loathe themselves for the evils which they have committed, in all their abominations.", "twenty": "", "jps": "And they that escape of you shall remember Me among the nations whither they shall be carried captives, how that I have been anguished with their straying heart, which hath departed from Me, and with their eyes, which are gone astray after their idols; and they shall loathe themselves in their own sight for the evils which they have committed in all their abominations.", "acv": "And those of you who escape shall remember me among the nations where they shall be carried captive, how I have broken with their lewd heart, which has departed from me, and with their eyes, which play the harlot after their idols. And they shall loathe themselves in their own sight for the evils which they have committed in all their abominations.", "anderson": "", "haweis": "", "noyes": "And they of you that escape shall remember me among the nations whither they shall be carried captives, when I have broken their whorish heart which departed from me, and their eyes which went lusting after their idols; and they shall loathe themselves for the evils which they have committed in all their abominations.", "webster": "And they that escape of you shall remember me among the nations whither they shall be carried captives, because I am broken with their apostate heart, which hath departed from me, and with their eyes which go astray after their idols: and they shall lothe themselves for the evils which they have committed in all their abominations.", "vulgate": "et recordabuntur mei liberati vestri in gentibus ad quas captivi ducti sunt quia contrivi cor eorum fornicans et recedens a me et oculos eorum fornicantes post idola sua et displicebunt sibimet super malis quae fecerunt in universis abominationibus suis;", "brenton": "then they of you that escape among the nations whither they were carried captive shall remember me; (I have sworn an oath against their heart that goes a-whoring from me, and their eyes that go a-whoring after their practices;) and they shall mourn over themselves for all their abominations."}}, {"v": 10, "ref": "6:10", "o": "וְ/יָדְע֖וּ כִּֽי אֲנִ֣י יְהוָ֑ה לֹ֤א אֶל חִנָּם֙ דִּבַּ֔רְתִּי לַ/עֲשׂ֥וֹת לָ/הֶ֖ם הָ/רָעָ֥ה הַ/זֹּֽאת", "en": {"kjv": "And they shall know that I am the Lord, and that I have not said in vain that I would do this evil unto them.", "web": "They shall know that I am Yahweh: I have not said in vain that I would do this evil to them.", "bsb": "And they will know that I am the LORD; I did not declare in vain that I would bring this calamity upon them.", "asv": "And they shall know that I am Jehovah: I have not said in vain that I would do this evil unto them.", "ylt": "And they have known that I am Jehovah, Not for nought have I spoken to do to them this evil.", "dra": "And they shall know that I the Lord have not spoken in vain that I would do this evil to them.", "bbe": "And they will be certain that I am the Lord: not for nothing did I say that I would do this evil to them.", "geneva": "And they shall knowe that I am the Lord, and that I haue not saide in vaine, that I woulde doe this euill vnto them.", "wycliffe": "And thei schulen wite, that Y the Lord spak not in veyn, that Y schulde do this yuel to hem.", "rotherham": "Then shall they know that, I, Yahweh,—not in vain, had threatened to bring upon them this calamity.", "darby": "And they shall know that I [am] Jehovah: I have not said in vain that I would do this evil unto them.", "twenty": "", "jps": "And they shall know that I am HaShem; I have not said in vain that I would do this evil unto them.", "acv": "And they shall know that I am Jehovah. I have not said in vain that I would do this evil to them.", "anderson": "", "haweis": "", "noyes": "Then shall they know that I am Jehovah, and that I have not said in vain, that I would do all this evil to them.", "webster": "And they shall know that I [am] the LORD, [and that] I have not said in vain that I would do this evil to them.", "vulgate": "et scient quia ego Dominus non frustra locutus sum ut facerem eis malum hoc;", "brenton": "And they shall know that I the Lord have spoken."}}, {"v": 11, "ref": "6:11", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה הַכֵּ֨ה בְ/כַפְּ/ךָ֜ וּ/רְקַ֤ע בְּ/רַגְלְ/ךָ֙ וֶֽ/אֱמָר אָ֔ח אֶ֛ל כָּל תּוֹעֲב֥וֹת רָע֖וֹת בֵּ֣ית יִשְׂרָאֵ֑ל אֲשֶׁ֗ר בַּ/חֶ֛רֶב בָּ/רָעָ֥ב וּ/בַ/דֶּ֖בֶר יִפֹּֽלוּ", "en": {"kjv": "Thus saith the Lord God; Smite with thine hand, and stamp with thy foot, and say, Alas for all the evil abominations of the house of Israel! for they shall fall by the sword, by the famine, and by the pestilence.", "web": "Thus says the Lord Yahweh: Strike with your hand, and stamp with your foot, and say, Alas! because of all the evil abominations of the house of Israel; for they shall fall by the sword, by the famine, and by the pestilence.", "bsb": "This is what the Lord GOD says: Clap your hands, stomp your feet, and cry out “Alas!” because of all the wicked abominations of the house of Israel, who will fall by sword and famine and plague.", "asv": "Thus saith the Lord Jehovah: Smite with thy hand, and stamp with thy foot, and say, Alas! because of all the evil abominations of the house of Israel; for they shall fall by the sword, by the famine, and by the pestilence.", "ylt": "Thus said the Lord Jehovah: `Smite with thy palm, and stamp with thy foot, And say: Alas, for all the evil abominations of the house of Israel, Who by sword, by famine, and by pestilence do fall.", "dra": "Thus saith the Lord God: Strike with thy hand and stamp with thy foot, and say: Alas, for all the abominations of the evils of the house of Israel: for they shall fall by the sword, by the famine, and by the pestilence.", "bbe": "This is what the Lord has said: Give blows with your hand, stamping with your foot, and say, O sorrow! because of all the evil and disgusting ways of the children of Israel: for death will overtake them by the sword and through need of food and by disease.", "geneva": "Thus saith the Lord God, Smite with thine hand, and stretch forth with thy foote, and say, Alas, for all the wicked abominations of the house of Israel: for they shall fall by the sworde, by the famine, and by the pestilence.", "wycliffe": "The Lord God seith these thingis, Smyte thin hond, and hurtle thi foot, and seie, Alas! to alle abhomynaciouns of the yuelis of the hous of Israel; for thei schulen falle doun bi swerd, hungur, and pestilence. He that is fer, shal die bi pestilence.", "rotherham": "Thus saith My Lord. Yahweh, Smite with thy hand, and stamp with thy foot and say, Alas! regarding all the wicked abominations of the house of Israel,—in that by sword, by famine, and by pestilence, shall they fall:", "darby": "Thus saith the Lord Jehovah: Smite with thy hand, and stamp with thy foot, and say, Alas for all the abominations of the iniquities of the house of Israel! for they shall fall by the sword, by the famine, and by the pestilence.", "twenty": "", "jps": "Thus saith the L-rd GOD: Smite with thy hand, and stamp with thy foot, and say: Alas! because of all the evil abominations of the house of Israel; for they shall fall by the sword, by the famine, and by the pestilence.", "acv": "Thus says the lord Jehovah: Smite with thy hand, and stamp with thy foot, and say, Alas! because of all the evil abominations of the house of Israel, for they shall fall by the sword, by the famine, and by the pestilence.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Smite upon thy hand, and stamp with thy foot, and say, Alas for all the evil abominations of the house of Israel! for by the sword, by famine, and by pestilence shall they fall.", "webster": "Thus saith the Lord GOD; Smite with thy hand, and stamp with thy foot, and say, Alas, for all the evil abominations of the house of Israel! for they shall fall by the sword, by the famine, and by the pestilence.", "vulgate": "haec dicit Dominus Deus percute manu tua et adlide pedem tuum et dic eheu ad omnes abominationes malorum domus Israhel qui gladio fame peste ruituri sunt;", "brenton": "Thus saith the Lord; Clap with thy hand, and stamp with thy foot and say, Aha, aha! for all the abominations of the house of Israel: they shall fall by the sword, and by pestilence, and by famine."}}, {"v": 12, "ref": "6:12", "o": "הָ/רָח֞וֹק בַּ/דֶּ֣בֶר יָמ֗וּת וְ/הַ/קָּרוֹב֙ בַּ/חֶ֣רֶב יִפּ֔וֹל וְ/הַ/נִּשְׁאָר֙ וְ/הַ/נָּצ֔וּר בָּ/רָעָ֖ב יָמ֑וּת וְ/כִלֵּיתִ֥י חֲמָתִ֖/י בָּֽ/ם", "en": {"kjv": "He that is far off shall die of the pestilence; and he that is near shall fall by the sword; and he that remaineth and is besieged shall die by the famine: thus will I accomplish my fury upon them.", "web": "He who is far off shall die of the pestilence; and he who is near shall fall by the sword; and he who remains and is besieged shall die by the famine: thus will I accomplish my wrath on them.", "bsb": "He who is far off will die by the plague, he who is near will fall by the sword, and he who remains will die by famine. So I will vent My fury upon them.", "asv": "He that is far off shall die of the pestilence; and he that is near shall fall by the sword; and he that remaineth and is besieged shall die by the famine: thus will I accomplish my wrath upon them.", "ylt": "The far-off by pestilence dieth, And the near by sword falleth, And the left and the besieged by famine dieth, And I have completed my fury upon them.", "dra": "He that is far off shall die of the pestilence: and he that is near, shall fall by the sword: and he that remaineth, and is besieged, shall die by the famine: and I will accomplish my indignation upon them.", "bbe": "He who is far away will come to his death by disease; he who is near will be put to the sword; he who is shut up will come to his death through need of food; and I will give full effect to my passion against them.", "geneva": "He that is farre off, shall dye of the pestilence, and he that is neere, shall fall by the sword, and hee that remaineth and is besieged, shall dye by the famine: thus will I accomplish my wrath vpon them.", "wycliffe": "Forsothe he that is niy, shal falle bi swerd. And he that is laft and bisegid, shal die bi hungur. And Y schal fille myn indignacioun in hem.", "rotherham": "He that is far off by pestilence, shall die and He that is near by the sword, shall fall, and He that is left and is besieged by the famine, shall die; Thus will I make an end of mine indignation against them.", "darby": "He that is far off shall die of the pestilence; and he that is near shall fall by the sword; and he that is left, and is besieged, shall die by the famine: and I will accomplish my fury upon them.", "twenty": "", "jps": "He that is far off shall die of the pestilence; and he that is near shall fall by the sword; and he that remaineth and is besieged shall die by the famine; thus will I spend My fury upon them.", "acv": "He who is far off shall die of the pestilence, and he who is near shall fall by the sword, and he who remains and is besieged shall die by the famine. Thus I will accomplish my wrath upon them.", "anderson": "", "haweis": "", "noyes": "He that is far off shall die by pestilence, and he that is near shall fall by the sword, and he that remaineth and is preserved shall die by famine. Thus will I accomplish my fury upon them.", "webster": "He that is far off shall die by the pestilence; and he that is near shall fall by the sword; and he that remaineth and is besieged shall die by the famine: thus will I accomplish my fury upon them.", "vulgate": "qui longe est peste morietur qui autem prope gladio corruet et qui relictus fuerit et obsessus fame morietur et conpleam indignationem meam in eis;", "brenton": "He that is near shall fall by the sword; and he that is far off shall die by the pestilence; and he that is in the siege shall be consumed with famine: and I will accomplish mine anger upon them."}}, {"v": 13, "ref": "6:13", "o": "וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה בִּֽ/הְי֣וֹת חַלְלֵי/הֶ֗ם בְּ/תוֹךְ֙ גִּלּ֣וּלֵי/הֶ֔ם סְבִיב֖וֹת מִזְבְּחֽוֹתֵי/הֶ֑ם אֶל֩ כָּל גִּבְעָ֨ה רָמָ֜ה בְּ/כֹ֣ל רָאשֵׁ֣י הֶ/הָרִ֗ים וְ/תַ֨חַת כָּל עֵ֤ץ רַֽעֲנָן֙ וְ/תַ֨חַת֙ כָּל אֵלָ֣ה עֲבֻתָּ֔ה מְק֗וֹם אֲשֶׁ֤ר נָֽתְנוּ שָׁם֙ רֵ֣יחַ נִיחֹ֔חַ לְ/כֹ֖ל גִּלּוּלֵי/הֶֽם", "en": {"kjv": "Then shall ye know that I am the Lord, when their slain men shall be among their idols round about their altars, upon every high hill, in all the tops of the mountains, and under every green tree, and under every thick oak, the place where they did offer sweet savour to all their idols.", "web": "You shall know that I am Yahweh, when their slain men shall be among their idols around their altars, on every high hill, on all the tops of the mountains, and under every green tree, and under every thick oak, the places where they offered pleasant aroma to all their idols.", "bsb": "Then you will know that I am the LORD, when their slain lie among their idols around their altars, on every high hill, on all the mountaintops, and under every green tree and leafy oak—the places where they offered fragrant incense to all their idols.", "asv": "And ye shall know that I am Jehovah, when their slain men shall be among their idols round about their altars, upon every high hill, on all the tops of the mountains, and under every green tree, and under every thick oak, the places where they offered sweet savor to all their idols.", "ylt": "And ye have known that I am Jehovah, In their wounded being in the midst of their idols, Round about their altars, On every high hill, on all tops of mountains, And under every green tree, and under every thick oak, The place where they gave sweet fragrance to all their idols.", "dra": "And you shall know that I am the Lord, when your slain shall be amongst your idols, round about your altars, in every high hill, and on all the tops of mountains, and under every woody tree, and under every thick oak, the place where they burnt sweet smelling frankincense to all their idols.", "bbe": "And you will be certain that I am the Lord, when their dead men are stretched among their images round about their altars on every high hill, on all the tops of the mountains, and under every branching tree, and under every thick oak-tree, the places where they made sweet smells to all their images.", "geneva": "Then ye shall knowe, that I am ye Lord, when their slaine men shalbe among their idoles round about their altars, vpon euerie hie hill in al the toppes of the mountaines, and vnder euery greene tree, and vnder euerie thicke oke, which is the place where they did offer sweete sauour to all their idoles.", "wycliffe": "And ye schulen wite, that Y am the Lord, whanne youre slayn men schulen be in the myddis of youre idols, in the cumpas of youre auteris, in eche hiy litil hil, and in alle the hiynessis of mounteyns, and vndur ech tree ful of wode, and vndur ech ook ful of boowis, that is, a place where thei brenten encense swete smellynge to alle her idols.", "rotherham": "So shall ye know that I, am Yahweh, In that their slain are in the midst of their manufactured gods, on every side of their altars,— Upon every high hill In all the tops of the mountains and Under every green tree and Under every tangled oak, The place where they offered a satisfying odour to all their manufactured gods.", "darby": "And ye shall know that I [am] Jehovah, when their slain shall be among their idols, round about their altars, upon every high hill, on all the tops of the mountains, and under every green tree, and under every thick terebinth, the places where they offered sweet savour to all their idols.", "twenty": "", "jps": "And ye shall know that I am HaShem, when their slain men shall be among their idols round about their altars, upon every high hill, in all the tops of the mountains, and under every leafy tree, and under every thick terebinth, the place where they did offer sweet savour to all their idols.", "acv": "And ye shall know that I am Jehovah when their slain men shall be among their idols round about their altars, upon every high hill, on all the tops of the mountains, and under every green tree, and under every thick oak, the places where they offered sweet savor to all their idols.", "anderson": "", "haweis": "", "noyes": "Then shall ye know that I am Jehovah, when their slain men shall be among their idols round about their altars, upon every high hill, upon all the tops of the mountains, and under every green tree, and under every thick oak, in every place where they offered sweet savor to all their idols.", "webster": "Then shall ye know that I [am] the LORD, when their slain [men] shall be among their idols round about their altars, upon every high hill, on all the tops of the mountains, and under every green tree, and under every thick oak, the place where they offered sweet savor to all their idols.", "vulgate": "et scietis quia ego Dominus cum fuerint interfecti vestri in medio idolorum vestrorum in circuitu ararum vestrarum in omni colle excelso in cunctis summitatibus montium et subtus omne lignum nemorosum et subtus universam quercum frondosam locum ubi accenderunt tura redolentia universis idolis suis;", "brenton": "Then ye shall know that I am the Lord, when your slain are in the midst of your idols round about your altars, on every high hill, and under every shady tree, where they offered a sweet savour to all their idols."}}, {"v": 14, "ref": "6:14", "o": "וְ/נָטִ֤יתִי אֶת יָדִ/י֙ עֲלֵי/הֶ֔ם וְ/נָתַתִּ֨י אֶת הָ/אָ֜רֶץ שְׁמָמָ֤ה וּ/מְשַׁמָּה֙ מִ/מִּדְבַּ֣ר דִּבְלָ֔תָ/ה בְּ/כֹ֖ל מוֹשְׁבֽוֹתֵי/הֶ֑ם וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "So will I stretch out my hand upon them, and make the land desolate, yea, more desolate than the wilderness toward Diblath, in all their habitations: and they shall know that I am the Lord.", "web": "I will stretch out my hand on them, and make the land desolate and waste, from the wilderness toward Diblah, throughout all their habitations: and they shall know that I am Yahweh.", "bsb": "I will stretch out My hand against them, and wherever they live I will make the land a desolate waste, from the wilderness to Diblah. Then they will know that I am the LORD.’”", "asv": "And I will stretch out my hand upon them, and make the land desolate and waste, from the wilderness toward Diblah, throughout all their habitations: and they shall know that I am Jehovah.", "ylt": "And I have stretched out my hand against them, And have made the land a desolation, Even a desolation from the wilderness to Diblath, In all their dwellings, And they have known that I am Jehovah!'", "dra": "And I will stretch forth my hand upon them: and I will make the land desolate, and abandoned from the desert of Deblatha in all their dwelling places: and they shall know that I am the Lord.", "bbe": "And my hand will be stretched out against them, making the land waste and unpeopled, from the waste land to Riblah, through all their living-places: and they will be certain that I am the Lord.", "geneva": "So will I stretch mine hand vpon them, and make the lande waste, and desolate from the wildernes vnto Diblath in all their habitations, and they shall know, that I am the Lord.", "wycliffe": "And Y schal stretche forth myn hond on hem, and Y schal make her lond desolat and destitute, fro desert Deblata, in alle the dwellyngis of hem; and thei schulen wite, that Y am the Lord.", "rotherham": "Thus will I stretch out my hand upon them, and make the land a greater waste and devastation than the desert toward Diblah throughout all their dwelling-places,- And they shall know that, I, am Yahweh.", "darby": "And I will stretch out my hand upon them, and make the land desolate, yea, more desolate than the wilderness of Diblath, in all their dwellings; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "And I will stretch out My hand upon them, and make the land desolate and waste, more than the wilderness of Diblah, throughout all their habitations; and they shall know that I am HaShem.'", "acv": "And I will stretch out my hand upon them, and make the land desolate and waste, from the wilderness toward Diblah, throughout all their habitations. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "So will I stretch out my hand against them, and make the land desolate; yea, more desolate than the wilderness toward Diblath, in all their habitations; and they shall know that I am Jehovah.", "webster": "So will I stretch out my hand upon them, and make the land desolate, even, more desolate than the wilderness towards Diblath, in all their habitations: and they shall know that I [am] the LORD.", "vulgate": "et extendam manum meam super eos et faciam terram desolatam et destitutam a deserto Deblatha in omnibus habitationibus eorum et scient quia ego Dominus;", "brenton": "And I will stretch out my hand against them, and I will make the land desolate and ruined from the wilderness of Deblatha, in all their habitations: and ye shall know that I am the Lord."}}]}, {"c": 7, "verses": [{"v": 1, "ref": "7:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying, `And thou, son of man, Thus said the Lord Jehovah to the ground of Israel:", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Moreover the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "Moreover the word of the Lord came to me, saying, Also, thou, son of man, say,"}}, {"v": 2, "ref": "7:2", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם כֹּה אָמַ֞ר אֲדֹנָ֧/י יְהוִ֛ה לְ/אַדְמַ֥ת יִשְׂרָאֵ֖ל קֵ֑ץ בָּ֣א הַ/קֵּ֔ץ עַל ארבעת אַרְבַּ֖ע כַּנְפ֥וֹת הָ/אָֽרֶץ", "en": {"kjv": "Also, thou son of man, thus saith the Lord God unto the land of Israel; An end, the end is come upon the four corners of the land.", "web": "You, son of man, thus says the Lord Yahweh to the land of Israel, An end: the end has come on the four corners of the land.", "bsb": "“O son of man, this is what the Lord GOD says to the land of Israel: ‘The end! The end has come upon the four corners of the land.", "asv": "And thou, son of man, thus saith the Lord Jehovah unto the land of Israel, An end: the end is come upon the four corners of the land.", "ylt": "An end, come hath the end on the four corners of the land.", "dra": "And thou son of man, thus saith the Lord God to the land of Israel: The end is come, the end is come upon the four quarters of the land.", "bbe": "And you, son of man, say, This is what the Lord has said to the land of Israel: An end has come, the end has come on the four quarters of the land.", "geneva": "Also thou sonne of man, thus saith the Lord God, An ende is come vnto the lande of Israel: the ende is come vpon the foure corners of the lande.", "wycliffe": "`and he seide, And thou, sone of man, the Lord God of the lond of Israel seith these thingis, The ende cometh, the ende cometh, on foure coostis of the lond.", "rotherham": "Thou therefore O son of man. Thus saith My Lord Yahweh, To the so of Israel, there is an end,- The end hath come upon the four skirts of the land.", "darby": "And thou, son of man, thus saith the Lord Jehovah unto the land of Israel: An end, the end is come upon the four corners of the land.", "twenty": "", "jps": "'And thou, son of man, thus saith the L-rd GOD concerning the land of Israel: An end! the end is come upon the four corners of the land.", "acv": "And thou, son of man, thus says the lord Jehovah to the land of Israel: An end. The end has come upon the four corners of the land.", "anderson": "", "haweis": "", "noyes": "Thou son of man, thus saith the Lord Jehovah concerning the land of Israel:—", "webster": "Also, thou son of man, thus saith the Lord GOD to the land of Israel; An end, the end is come upon the four corners of the land.", "vulgate": "et tu fili hominis haec dicit Dominus Deus terrae Israhel finis venit finis super quattuor plagas terrae;", "brenton": "Thus saith the Lord; An end is come to the land of Israel, the end is come on the four corners of the land."}}, {"v": 3, "ref": "7:3", "o": "עַתָּה֙ הַ/קֵּ֣ץ עָלַ֔יִ/ךְ וְ/שִׁלַּחְתִּ֤י אַפִּ/י֙ בָּ֔/ךְ וּ/שְׁפַטְתִּ֖י/ךְ כִּ/דְרָכָ֑יִ/ךְ וְ/נָתַתִּ֣י עָלַ֔יִ/ךְ אֵ֖ת כָּל תּוֹעֲבֹתָֽיִ/ךְ", "en": {"kjv": "Now is the end come upon thee, and I will send mine anger upon thee, and will judge thee according to thy ways, and will recompense upon thee all thine abominations.", "web": "Now is the end on you, and I will send my anger on you, and will judge you according to your ways; and I will bring on you all your abominations.", "bsb": "The end is now upon you, and I will unleash My anger against you. I will judge you according to your ways and repay you for all your abominations.", "asv": "Now is the end upon thee, and I will send mine anger upon thee, and will judge thee according to thy ways; and I will bring upon thee all thine abominations.", "ylt": "Now is the end unto thee, And I have sent Mine anger upon thee, And judged thee according to thy ways, And set against thee all thine abominations.", "dra": "Now is an end come upon thee, and I will send my wrath upon thee, and I will judge thee according to thy ways: and I will set all thy abominations against thee.", "bbe": "Now the end has come on you, and I will send my wrath on you, judging you for your ways, I will send punishment on you for all your disgusting acts.", "geneva": "Nowe is the ende come vpon thee, and I wil sende my wrath vpon thee, and will iudge thee according to thy wayes, and will laye vpon thee all thine abominations.", "wycliffe": "Now an ende is on thee, and Y shal sende in my strong veniaunce on thee, and Y schal deme thee bi thi weies, and Y schal sette alle thin abhomynaciouns ayens thee.", "rotherham": "Now is the end upon thee, Therefore will I send mine anger against thee, And judge thee according to thy ways,- And lay upon thee all thine abominations;", "darby": "Now is the end upon thee; and I will send mine anger upon thee, and will judge thee according to thy ways, and will bring upon thee all thine abominations.", "twenty": "", "jps": "Now is the end upon thee, and I will send Mine anger upon thee, and will judge thee according to thy ways; and I will bring upon thee all thine abominations.", "acv": "Now the end is upon thee, and I will send my anger upon thee, and will judge thee according to thy ways. And I will bring upon thee all thine abominations.", "anderson": "", "haweis": "", "noyes": "The end cometh, the end cometh, Upon the four corners of the land! Now cometh the end upon thee! For I will send my anger upon thee, And will judge thee according to thy ways, And will recompense upon thee all thine abominations.", "webster": "Now [is] the end [come] upon thee, and I will send my anger upon thee, and will judge thee according to thy ways, and will recompense upon thee all thy abominations.", "vulgate": "nunc finis super te et emittam furorem meum in te et iudicabo te iuxta vias tuas et ponam contra te omnes abominationes tuas;", "brenton": "The end is come on thee,"}}, {"v": 4, "ref": "7:4", "o": "וְ/לֹא תָח֥וֹס עֵינִ֛/י עָלַ֖יִ/ךְ וְ/לֹ֣א אֶחְמ֑וֹל כִּ֣י דְרָכַ֜יִ/ךְ עָלַ֣יִ/ךְ אֶתֵּ֗ן וְ/תוֹעֲבוֹתַ֨יִ/ךְ֙ בְּ/תוֹכֵ֣/ךְ תִּֽהְיֶ֔יןָ וִ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And mine eye shall not spare thee, neither will I have pity: but I will recompense thy ways upon thee, and thine abominations shall be in the midst of thee: and ye shall know that I am the Lord.", "web": "My eye shall not spare you, neither will I have pity; but I will bring your ways on you, and your abominations shall be in your midst: and you shall know that I am Yahweh.", "bsb": "I will not look on you with pity, nor will I spare you, but I will punish you for your ways and for the abominations among you. Then you will know that I am the LORD.’", "asv": "And mine eye shall not spare thee, neither will I have pity; but I will bring thy ways upon thee, and thine abominations shall be in the midst of thee: and ye shall know that I am Jehovah.", "ylt": "And no pity on thee hath Mine eye, nor do I spare, For thy ways against thee I do set, And thine abominations are in thy midst, And ye have known that I am Jehovah.", "dra": "And my eye shall not spare thee, and I will shew thee no pity: but I will lay thy ways upon thee, and thy abominations shall be in the midst of thee: and you shall know that I am the Lord.", "bbe": "My eye will not have mercy on you, and I will have no pity: but I will send the punishment of your ways on you, and your disgusting works will be among you: and you will be certain that I am the Lord.", "geneva": "Neither shall mine eye spare thee, neither will I haue pitie: but I will laye thy waies vpon thee: and thine abomination shall bee in the middes of thee, and yee shall knowe that I am the Lord.", "wycliffe": "And myn iye shal not spare on thee, and Y schal not do mercy. But Y shal sette thi weies on thee, and thin abhomynaciouns schulen be in the myddis of thee; and ye schulen wite, that Y am the Lord.", "rotherham": "And mine eye shall not shield thee. Neither will I pity,—. For thy ways—upon thee, will I lay. And thine abominations in thy midst, shall be found, So shall ye know that, I, am Yahweh.", "darby": "And mine eye shall not spare thee, neither will I have pity; but I will bring thy ways upon thee, and thine abominations shall be in the midst of thee; and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "And Mine eye shall not spare thee, neither will I have pity; but I will bring thy ways upon thee, and thine abominations shall be in the midst of thee; and ye shall know that I am HaShem.", "acv": "And my eye shall not spare thee, nor will I have pity. But I will bring thy ways upon thee, and thine abominations shall be in the midst of thee. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And mine eye shall not spare thee, neither will I have pity; But I will recompense thy ways upon thee, And thine abominations shall be in the midst of thee; And ye shall know that I am Jehovah.", "webster": "And my eye shall not spare thee, neither will I have pity: but I will recompense thy ways upon thee, and thy abominations shall be in the midst of thee: and ye shall know that I [am] the LORD.", "vulgate": "et non parcet oculus meus super te et non miserebor sed vias tuas ponam super te et abominationes tuae in medio tui erunt et scietis quia ego Dominus;", "brenton": "the inhabitant of the land: the time is come, the day has drawn nigh, not with tumult, nor with pangs."}}, {"v": 5, "ref": "7:5", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה רָעָ֛ה אַחַ֥ת רָעָ֖ה הִנֵּ֥ה בָאָֽה", "en": {"kjv": "Thus saith the Lord God; An evil, an only evil, behold, is come.", "web": "Thus says the Lord Yahweh: An evil, an only evil; behold, it comes.", "bsb": "This is what the Lord GOD says: ‘Disaster! An unprecedented disaster— behold, it is coming!", "asv": "Thus saith the Lord Jehovah: An evil, an only evil; behold, it cometh.", "ylt": "Thus said the Lord Jehovah: Evil, a single evil, lo, it hath come.", "dra": "Thus saith the Lord God: One affliction, behold an affliction is come.", "bbe": "This is what the Lord has said: An evil, even one evil; see, it is coming.", "geneva": "Thus saith the Lord God, Beholde, one euil, euen one euill is come.", "wycliffe": "The Lord God seith these thingis, O turment, lo!", "rotherham": "Thus saith My Lord Yahweh:A calamity, a sole calamity, lo! it hath come.", "darby": "Thus saith the Lord Jehovah: An evil, an only evil! behold, it is come.", "twenty": "", "jps": "Thus saith the L-rd GOD: An evil, a singular evil, behold, it cometh.", "acv": "Thus says the lord Jehovah: An evil, an only evil, behold, it comes.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: An evil, an unheard-of evil, behold, it cometh!", "webster": "Thus saith the Lord GOD; An evil, an only evil, behold, is come.", "vulgate": "haec dicit Dominus Deus adflictio una adflictio ecce venit;", "brenton": "Now I will pour out my anger upon thee near at hand, and I will accomplish my wrath on thee: and I will judge thee for thy ways, and recompense upon thee all thine abominations."}}, {"v": 6, "ref": "7:6", "o": "קֵ֣ץ בָּ֔א בָּ֥א הַ/קֵּ֖ץ הֵקִ֣יץ אֵלָ֑יִ/ךְ הִנֵּ֖ה בָּאָֽה", "en": {"kjv": "An end is come, the end is come: it watcheth for thee; behold, it is come.", "web": "An end has come, the end has come; it awakes against you; behold, it comes.", "bsb": "The end has come! The end has come! It has roused itself against you. Behold, it has come!", "asv": "An end is come, the end is come; it awaketh against thee; behold, it cometh.", "ylt": "An end hath come, come hath the end, It hath waked for thee, lo, it hath come.", "dra": "An end is come, the end is come, it hath awaked against thee: behold it is come.", "bbe": "An end has come, the end has come; see, it is coming on you.", "geneva": "An ende is come, the end is come, it watched for thee: beholde, it is come.", "wycliffe": "turment cometh; the ende cometh, the ende cometh; it schal wake fulli ayens thee; lo! it cometh.", "rotherham": "An end hath come, Come hath the end It hath roused itself up against thee,— Lo! it hath come.", "darby": "The end is come, the end is come; it awaketh against thee: behold, it cometh.", "twenty": "", "jps": "An end is come, the end is come, it awaketh against thee; behold, it cometh.", "acv": "An end has come. The end has come. It awakens against thee. Behold, it comes.", "anderson": "", "haweis": "", "noyes": "The end cometh, the end cometh! It awaketh against thee, behold, it cometh!", "webster": "An end is come, the end is come: it watcheth for thee; behold, it is come.", "vulgate": "finis venit venit finis evigilavit adversum te ecce venit;", "brenton": "Mine eye shall not spare, nor will I have any mercy: for I will recompense thy ways upon thee, and thine abominations shall be in the midst of thee; and thou shalt know that I am the Lord that smite thee."}}, {"v": 7, "ref": "7:7", "o": "בָּ֧אָה הַ/צְּפִירָ֛ה אֵלֶ֖י/ךָ יוֹשֵׁ֣ב הָ/אָ֑רֶץ בָּ֣א הָ/עֵ֗ת קָר֛וֹב הַ/יּ֥וֹם מְהוּמָ֖ה וְ/לֹא הֵ֥ד הָרִֽים", "en": {"kjv": "The morning is come unto thee, O thou that dwellest in the land: the time is come, the day of trouble is near, and not the sounding again of the mountains.", "web": "Your doom has come to you, inhabitant of the land: the time has come, the day is near, a day of tumult, and not of joyful shouting, on the mountains.", "bsb": "Doom has come to you, O inhabitants of the land. The time has come; the day is near; there is panic on the mountains instead of shouts of joy.", "asv": "Thy doom is come unto thee, O inhabitant of the land: the time is come, the day is near, a day of tumult, and not of joyful shouting, upon the mountains.", "ylt": "Come hath the morning unto thee, O inhabitant of the land! Come hath the time, near is a day of trouble, And not the shouting of mountains.", "dra": "Destruction is come upon thee that dwellest in the land: the time is come, the day of slaughter is near, and not of the joy of mountains.", "bbe": "The crowning time has come on you, O people of the land: the time has come, the day is near; the day will not be slow in coming, it will not keep back.", "geneva": "The morning is come vnto thee, that dwellest in the lande: the time is come, the day of trouble is neere, and not the sounding againe of the mountaines.", "wycliffe": "Sorewe cometh on thee, that dwellist in the lond; the tyme cometh, the dai of sleyng is niy, and not of glorie of hillis.", "rotherham": "The circle hath come round unto thee. O inhabitant of the land,- The time, hath come, The day of consternation, hath drawn near. And not the joyful shout of the mountains.", "darby": "The doom is come unto thee, inhabitant of the land; the time is come, the day is near, — tumult, and not the joyous cry from the mountains.", "twenty": "", "jps": "The turn is come unto thee, O inhabitant of the land; the time is come, the day of tumult is near, and not of joyful shouting upon the mountains.", "acv": "Thy doom has come to thee, O inhabitant of the land. The time has come. The day is near, tumult, and not joyful shouting, upon the mountains.", "anderson": "", "haweis": "", "noyes": "Thy fate cometh upon thee, thou that dwellest in the land! The time is come, The day of tumult is near, When no sound of joy shall be upon the mountains.", "webster": "The morning is come upon thee, O thou that dwellest in the land: the time is come, the day of trouble [is] near, and not the sounding again of the mountains.", "vulgate": "venit contractio super te qui habitas in terra venit tempus prope est dies occisionis et non gloriae montium;", "brenton": "Now the end is come to thee, and I will send judgment upon thee: and I will take vengeance on thy ways, and will recompense all thine abominations upon thee."}}, {"v": 8, "ref": "7:8", "o": "עַתָּ֣ה מִ/קָּר֗וֹב אֶשְׁפּ֤וֹךְ חֲמָתִ/י֙ עָלַ֔יִ/ךְ וְ/כִלֵּיתִ֤י אַפִּ/י֙ בָּ֔/ךְ וּ/שְׁפַטְתִּ֖י/ךְ כִּ/דְרָכָ֑יִ/ךְ וְ/נָתַתִּ֣י עָלַ֔יִ/ךְ אֵ֖ת כָּל תּוֹעֲבוֹתָֽיִ/ךְ", "en": {"kjv": "Now will I shortly pour out my fury upon thee, and accomplish mine anger upon thee: and I will judge thee according to thy ways, and will recompense thee for all thine abominations.", "web": "Now will I shortly pour out my wrath on you, and accomplish my anger against you, and will judge you according to your ways; and I will bring on you all your abominations.", "bsb": "Very soon I will pour out My wrath upon you and vent My anger against you; I will judge you according to your ways and repay you for all your abominations.", "asv": "Now will I shortly pour out my wrath upon thee, and accomplish mine anger against thee, and will judge thee according to thy ways; and I will bring upon thee all thine abominations.", "ylt": "Now, shortly I pour out My fury on thee, And have completed Mine anger against thee, And judged thee according to thy ways, And set against thee all thine abominations.", "dra": "Now very shortly I will pour out my wrath upon thee, and I will accomplish my anger in thee: and I will judge thee according to thy ways, and I will lay upon thee all thy crimes.", "bbe": "Now, in a little time, I will let loose my passion on you, and give full effect to my wrath against you, judging you for your ways, and sending punishment on you for all your disgusting works.", "geneva": "Now I will shortly powre out my wrath vpon thee, and fulfil mine anger vpon thee: I will iudge thee according to thy wayes, and will lay vpon thee all thine abominations.", "wycliffe": "Now anoon Y schal schede out myn ire on thee, and Y schal fille my strong veniaunce in thee; and Y schal deme thee bi thi weies, and Y schal putte to thee alle thi grete trespassis.", "rotherham": "Now shortly, will I pour out mine indignation upon thee, And will bring to an end mine anger against thee, And will judge thee according to thy ways,- And will lay upon thee all thine abominations.", "darby": "Now will I soon pour out my fury upon thee, and accomplish mine anger against thee; and I will judge thee according to thy ways, and will bring upon thee all thine abominations.", "twenty": "", "jps": "Now will I shortly pour out My fury upon thee, and spend Mine anger upon thee, and will judge thee according to thy ways; and I will bring upon thee all thine abominations.", "acv": "Now I will shortly pour out my wrath upon thee, and accomplish my anger against thee, and will judge thee according to thy ways. And I will bring upon thee all thine abominations.", "anderson": "", "haweis": "", "noyes": "Now will I shortly pour out my fury upon thee, And accomplish mine anger against thee; And I will judge thee according to thy ways, And recompense upon thee all thine abominations.", "webster": "Now will I shortly pour out my fury upon thee, and accomplish my anger upon thee: and I will judge thee according to thy ways, and will recompense thee for all thy abominations.", "vulgate": "nunc de propinquo effundam iram meam super te et conpleam furorem meum in te et iudicabo te iuxta vias tuas et inponam tibi omnia scelera tua;", "brenton": "Mine eye shall not spare, nor will I have any mercy: for I will recompense thy way upon thee, and thine abominations shall be in the midst of thee; and thou shalt know that I am the Lord."}}, {"v": 9, "ref": "7:9", "o": "וְ/לֹא תָח֥וֹס עֵינִ֖/י וְ/לֹ֣א אֶחְמ֑וֹל כִּ/דְרָכַ֜יִ/ךְ עָלַ֣יִ/ךְ אֶתֵּ֗ן וְ/תוֹעֲבוֹתַ֨יִ/ךְ֙ בְּ/תוֹכֵ֣/ךְ תִּֽהְיֶ֔יןָ וִֽ/ידַעְתֶּ֕ם כִּ֛י אֲנִ֥י יְהוָ֖ה מַכֶּֽה", "en": {"kjv": "And mine eye shall not spare, neither will I have pity: I will recompense thee according to thy ways and thine abominations that are in the midst of thee; and ye shall know that I am the Lord that smiteth.", "web": "My eye shall not spare, neither will I have pity: I will bring on you according to your ways; and your abominations shall be in your midst; and you shall know that I, Yahweh, do strike.", "bsb": "I will not look on you with pity, nor will I spare you, but I will punish you for your ways and for the abominations among you. Then you will know that it is I, the LORD, who strikes the blow.", "asv": "And mine eye shall not spare, neither will I have pity: I will bring upon thee according to thy ways; and thine abominations shall be in the midst of thee; and ye shall know that I, Jehovah, do smite.", "ylt": "And not pity doth Mine eye, nor do I spare, According to thy ways unto thee I give, And thine abominations are in thy midst, And ye have known that I am Jehovah the smiter.", "dra": "And my eye shall not spare, neither will I shew mercy: but I will lay thy ways upon thee, and thy abominations shall be in the midst of thee: and you shall know that I am the Lord that strike.", "bbe": "My eye will not have mercy, and I will have no pity: I will send on you the punishment of your ways, and your disgusting works will be among you; and you will see that I am the Lord who gives punishment.", "geneva": "Neither shall mine eie spare thee, neither will I haue pitie, but I will laye vpon thee according to thy wayes, and thine abominations shalbe in the middes of thee, and ye shall knowe that I am the Lord that smiteth.", "wycliffe": "And myn iye schal not spare, nether Y schal do merci; but Y schal putte on thee thi weies, and thin abhomynaciouns schulen be in the myddis of thee; and ye schulen wite, that Y am the Lord smytynge.", "rotherham": "And mine eye shall not shield thee Neither will I have pity,— According to thy ways, unto thee will I render, And thine abominations, in thy midst shall be found, So shall ye know that I, Yahweh am smiting.", "darby": "And mine eye shall not spare, neither will I have pity: I will render unto thee according to thy ways, and thine abominations shall be in the midst of thee; and ye shall know that it is I, Jehovah, that smite.", "twenty": "", "jps": "And Mine eye shall not spare, neither will I have pity; I will bring upon thee according to thy ways, and thine abominations shall be in the midst of thee; and ye shall know that I HaShem do smite.", "acv": "And my eye shall not spare, nor will I have pity. I will bring upon thee according to thy ways. And thine abominations shall be in the midst of thee. And ye shall know that I, Jehovah, do smite.", "anderson": "", "haweis": "", "noyes": "And mine eye shall not spare, neither will I have pity; I will recompense thee according to thy ways, And thine abominations shall come upon thee; And ye shall know that I, Jehovah, smite you.", "webster": "And my eye shall not spare, neither will I have pity: I will recompense thee according to thy ways and thy abominations [that] are in the midst of thee; and ye shall know that I [am] the LORD that smiteth.", "vulgate": "et non parcet oculus meus neque miserebor sed vias tuas inponam tibi et abominationes tuae in medio tui erunt et scietis quia ego sum Dominus percutiens;", "brenton": "For thus saith the Lord; Behold, the end is come."}}, {"v": 10, "ref": "7:10", "o": "הִנֵּ֥ה הַ/יּ֖וֹם הִנֵּ֣ה בָאָ֑ה יָֽצְאָה֙ הַ/צְּפִרָ֔ה צָ֚ץ הַ/מַּטֶּ֔ה פָּרַ֖ח הַ/זָּדֽוֹן", "en": {"kjv": "Behold the day, behold, it is come: the morning is gone forth; the rod hath blossomed, pride hath budded.", "web": "Behold, the day, behold, it comes: your doom has gone out; the rod has blossomed, pride has budded.", "bsb": "Behold, the day is here! It has come! Doom has gone out, the rod has budded, arrogance has bloomed.", "asv": "Behold, the day, behold, it cometh: thy doom is gone forth; the rod hath blossomed, pride hath budded.", "ylt": "Lo, the day, lo, it hath come, Gone forth hath the morning, Blossomed hath the rod, flourished the pride.", "dra": "Behold the day, behold it is come: destruction is gone forth, the rod hath blossomed, pride hath budded.", "bbe": "See, the day; see, it is coming: the crowning time has gone out; the twisted way is flowering, pride has put out buds.", "geneva": "Beholde, the day, beholde, it is come: the morning is gone forth, the rod florisheth: pride hath budded.", "wycliffe": "Lo! the dai, lo! it cometh; sorewe is gon out. A yerde flouride,", "rotherham": "Lo! the day, Lo! it hath come, The circle, hath gone forth, The sceptre, hath blossomed, Insolence hath sprouted:", "darby": "Behold the day, behold, it is come: the doom is gone forth; the rod hath blossomed, pride is full blown.", "twenty": "", "jps": "Behold the day; behold, it cometh; the turn is come forth; the rod hath blossomed, arrogancy hath budded.", "acv": "Behold, the day, behold, it comes. Thy doom has gone forth. The rod has blossomed; pride has budded.", "anderson": "", "haweis": "", "noyes": "Behold, the day, behold, it cometh! The destiny draweth near; The rod hath blossomed, pride hath flourished.", "webster": "Behold the day, behold, it is come; the morning is gone forth; the rod hath blossomed, pride hath budded.", "vulgate": "ecce dies ecce venit egressa est contractio floruit virga germinavit superbia;", "brenton": "Behold, the day of the Lord! although the rod has blossomed,"}}, {"v": 11, "ref": "7:11", "o": "הֶ/חָמָ֥ס קָ֖ם לְ/מַטֵּה רֶ֑שַׁע לֹא מֵ/הֶ֞ם וְ/לֹ֧א מֵ/הֲמוֹנָ֛/ם וְ/לֹ֥א מֶ/הֱמֵ/הֶ֖ם וְ/לֹא נֹ֥הַּ בָּ/הֶֽם", "en": {"kjv": "Violence is risen up into a rod of wickedness: none of them shall remain, nor of their multitude, nor of any of theirs: neither shall there be wailing for them.", "web": "Violence has risen up into a rod of wickedness. None of them shall remain, nor of their multitude, nor of their wealth. There shall be nothing of value among them.", "bsb": "Their violence has grown into a rod to punish their wickedness. None of them will remain: none of their multitude, none of their wealth, and nothing of value.", "asv": "Violence is risen up into a rod of wickedness; none of them shall remain, nor of their multitude, nor of their wealth: neither shall there be eminency among them.", "ylt": "The violence hath risen to a rod of wickedness, There is none of them, nor of their multitude, Nor of their noise, nor is there wailing for them.", "dra": "Iniquity is risen up into a rod of impiety: nothing of them shall remain, nor of their people, nor of the noise of them: and there shall be no rest among them.", "bbe": "Violent behaviour has been lifted up into a rod of evil; it will not be slow in coming, it will not keep back.", "geneva": "Crueltie is risen vp into a rod of wickednes: none of them shall remaine, nor of their riches, nor of any of theirs, neither shall there bee lamentation for them.", "wycliffe": "pride buriownede, wickidnesse roos in the yerde of vnpitee; not of hem, and not of the puple, nether of the sown of hem, and no reste shal be in hem.", "rotherham": "Violence hath risen up as a sceptre of lawlessness, —There are none of them And none of their multitude And none of their throngs And no lamentation over them.", "darby": "Violence is risen up into a rod of wickedness: nothing of them [shall remain], nor of their multitude, nor of their wealth, nor of the magnificence in the midst of them.", "twenty": "", "jps": "Violence is risen up into a rod of wickedness; nought cometh from them, nor from their tumult, nor from their turmoil, neither is there eminency among them.", "acv": "Violence has risen up into a rod of wickedness. None of them shall remain, nor of their multitude, nor of their wealth. Neither shall there be eminency among them.", "anderson": "", "haweis": "", "noyes": "Violence is risen up into a rod of wickedness; None of them shall remain, none of their multitude, none of their crowd; Nor shall there be wailing for them.", "webster": "Violence hath risen into a rod of wickedness: none of them [shall remain], nor of their multitude, nor of any of theirs: neither [shall there be] wailing for them.", "vulgate": "iniquitas surrexit in virga impietatis non ex eis et non ex populo neque ex sonitu eorum et non erit requies in eis;", "brenton": "pride has sprung up, and will break the staff of the wicked one, and that not with tumult, nor with haste."}}, {"v": 12, "ref": "7:12", "o": "בָּ֤א הָ/עֵת֙ הִגִּ֣יעַ הַ/יּ֔וֹם הַ/קּוֹנֶה֙ אַל יִשְׂמָ֔ח וְ/הַ/מּוֹכֵ֖ר אַל יִתְאַבָּ֑ל כִּ֥י חָר֖וֹן אֶל כָּל הֲמוֹנָֽ/הּ", "en": {"kjv": "The time is come, the day draweth near: let not the buyer rejoice, nor the seller mourn: for wrath is upon all the multitude thereof.", "web": "The time has come, the day draws near: don’t let the buyer rejoice, nor the seller mourn; for wrath is on all its multitude.", "bsb": "The time has come; the day has arrived. Let the buyer not rejoice and the seller not mourn, for wrath is upon the whole multitude.", "asv": "The time is come, the day draweth near: let not the buyer rejoice, nor the seller mourn; for wrath is upon all the multitude thereof.", "ylt": "Come hath the time, arrived hath the day, The buyer doth not rejoice, And the seller doth not become a mourner, For wrath is unto all its multitude.", "dra": "The time is come, the day is at hand: let not the buyer rejoice: nor the seller mourn: for wrath is upon all the people thereof.", "bbe": "The time has come, the day is near: let not him who gives a price for goods be glad, or him who gets the price have sorrow:", "geneva": "The time is come, the day draweth neere: let not the byer reioyce, nor let him that selleth, mourne: for the wrath is vpon al the multitude thereof.", "wycliffe": "The tyme cometh, the dai neiyede; he that bieth, be not glad, and he that sillith, mourne not; for whi ire is on al the puple therof.", "rotherham": "The time hath come. The day hath arrived, The buyer, let him not rejoice, and The seller, let him not mourn,— For indignation, is against all her multitude.", "darby": "The time is come, the day draweth near: let not the buyer rejoice, nor the seller mourn; for fierce anger is upon all the multitude thereof.", "twenty": "", "jps": "The time is come, the day draweth near; let not the buyer rejoice, nor the seller mourn; for wrath is upon all the multitude thereof.", "acv": "The time has come; the day draws near. Let not the buyer rejoice, nor the seller mourn, for wrath is upon all the multitude of it.", "anderson": "", "haweis": "", "noyes": "The time cometh, the day draweth near! Let not the buyer rejoice, Nor the seller mourn; For wrath is against their whole multitude.", "webster": "The time is come, the day draweth near: let not the buyer rejoice, nor the seller mourn: for wrath [is] upon all the multitude thereof.", "vulgate": "venit tempus adpropinquavit dies qui emit non laetetur et qui vendit non lugeat quia ira super omnem populum eius;", "brenton": "The time is come, behold the day: let not the buyer rejoice, and let not the seller mourn."}}, {"v": 13, "ref": "7:13", "o": "כִּ֣י הַ/מּוֹכֵ֗ר אֶל הַ/מִּמְכָּר֙ לֹ֣א יָשׁ֔וּב וְ/ע֥וֹד בַּ/חַיִּ֖ים חַיָּתָ֑/ם כִּֽי חָז֤וֹן אֶל כָּל הֲמוֹנָ/הּ֙ לֹ֣א יָשׁ֔וּב וְ/אִ֧ישׁ בַּ/עֲוֺנ֛/וֹ חַיָּת֖/וֹ לֹ֥א יִתְחַזָּֽקוּ", "en": {"kjv": "For the seller shall not return to that which is sold, although they were yet alive: for the vision is touching the whole multitude thereof, which shall not return; neither shall any strengthen himself in the iniquity of his life.", "web": "For the seller shall not return to that which is sold, although they be yet alive: for the vision is touching the whole multitude of it, none shall return; neither shall any strengthen himself in the iniquity of his life.", "bsb": "The seller will surely not recover what he sold while both remain alive. For the vision concerning the whole multitude will not be revoked, and because of their iniquity, not one of them will preserve his life.", "asv": "For the seller shall not return to that which is sold, although they be yet alive: for the vision is touching the whole multitude thereof, none shall return; neither shall any strengthen himself in the iniquity of his life.", "ylt": "For the seller to the sold thing turneth not, And yet among the living is their life, For the vision is unto all its multitude, It doth not turn back, And none by his iniquity doth strengthen his life.", "dra": "For the seller shall not return to that which he hath sold, although their life be yet among the living. For the vision which regardeth all the multitude thereof, shall not go back: neither shall man be strengthened in the iniquity of his life.", "bbe": "For the trader will not go back to the things for which he had his price, even while he is still living:", "geneva": "For hee that selleth, shall not returne to that which is solde, although they were yet aliue: for the vision was vnto al the multitude thereof, and they returned not, neither doeth any encourage himselfe in the punishment of his life.", "wycliffe": "For he that sillith, schal not turne ayen to that that he seelde, and yit the lijf of hem is in lyueris; for whi the reuelacioun to al the multitude therof shal not go ayen, and a man schal not be coumfortid in the wickidnesse of his lijf.", "rotherham": "For the seller, unto that which is to be sold, shall not return, though yet among the living, were their life, for the vision is against all her multitude. He shall not return, And, no man, by his punishment, shall strengthen, his life.", "darby": "For the seller shall not return to that which is sold, even though he were yet alive amongst the living: for the vision is touching the whole multitude thereof; it shall not be revoked; and none shall through his iniquity assure his life.", "twenty": "", "jps": "For the seller shall not return to that which is sold, although they be yet alive; for the vision is touching the whole multitude thereof, which shall not return; neither shall any stand possessed of the iniquity of his life.", "acv": "For the seller shall not return to that which is sold, although they be yet alive, for the vision is concerning the whole multitude of it. None shall return, nor shall any strengthen himself in the iniquity of his life.", "anderson": "", "haweis": "", "noyes": "For the seller shall not return to that which is sold, Though he be yet alive; For the vision against their whole multitude shall not return void, And none that liveth in his iniquity shall strengthen himself", "webster": "For the seller shall not return to that which is sold, although they were yet alive: for the vision [is] concerning the whole multitude thereof, [which] shall not return; neither shall any strengthen himself in the iniquity of his life.", "vulgate": "quia qui vendit ad id quod vendidit non revertetur et adhuc in viventibus vita eorum visio enim ad omnem multitudinem eius non regredietur et vir in iniquitate vitae suae non confortabitur;", "brenton": "For the buyer shall never again return to the seller, neither shall a man cleave with the eye of hope to his life."}}, {"v": 14, "ref": "7:14", "o": "תָּקְע֤וּ בַ/תָּק֨וֹעַ֙ וְ/הָכִ֣ין הַ/כֹּ֔ל וְ/אֵ֥ין הֹלֵ֖ךְ לַ/מִּלְחָמָ֑ה כִּ֥י חֲרוֹנִ֖/י אֶל כָּל הֲמוֹנָֽ/הּ", "en": {"kjv": "They have blown the trumpet, even to make all ready; but none goeth to the battle: for my wrath is upon all the multitude thereof.", "web": "They have blown the trumpet, and have made all ready; but no one goes to the battle; for my wrath is on all its multitude.", "bsb": "They have blown the trumpet and made everything ready, but no one goes to war, for My wrath is upon the whole multitude.", "asv": "They have blown the trumpet, and have made all ready; but none goeth to the battle; for my wrath is upon all the multitude thereof.", "ylt": "They have blown with a trumpet to prepare the whole, And none is going to battle, For My wrath is unto all its multitude.", "dra": "Blow the trumpet, let all be made ready, yet there is none to go to the battle: for my wrath shall be upon all the people thereof.", "bbe": "And he who has given a price for goods will not get them, for my wrath is on all of them.", "geneva": "They haue blowen the trumpet, and prepared all, but none goeth to the battel: for my wrath is vpon all the multitude thereof.", "wycliffe": "Synge ye with a trumpe, alle men be maad redi, and noon is that schal go to batel; for whi my wraththe is on al the puple therof.", "rotherham": "They have blown the trumpet, even to make All ready, Yet is there none going to the battle; For mine indignation is against all her multitude.", "darby": "They have blown the trumpet and made all ready, but none goeth to the battle; for my fierce anger is upon all the multitude thereof.", "twenty": "", "jps": "They have blown the horn, and have made all ready, but none goeth to the battle; for My wrath is upon all the multitude thereof.", "acv": "They have blown the trumpet, and have made all ready, but none goes to the battle, for my wrath is upon all the multitude of it.", "anderson": "", "haweis": "", "noyes": "\"Blow ye the trumpet, and let all be ready!\" Yet none goeth to the battle; For mine anger is against their whole multitude.", "webster": "They have blown the trumpet, even to make all ready; but none goeth to the battle: for my wrath [is] upon all the multitude thereof:", "vulgate": "canite tuba praeparentur omnes et non est qui vadat ad proelium ira enim mea super universum populum eius;", "brenton": "Sound ye the trumpet, and pass sentence on all together."}}, {"v": 15, "ref": "7:15", "o": "הַ/חֶ֣רֶב בַּ/ח֔וּץ וְ/הַ/דֶּ֥בֶר וְ/הָ/רָעָ֖ב מִ/בָּ֑יִת אֲשֶׁ֤ר בַּ/שָּׂדֶה֙ בַּ/חֶ֣רֶב יָמ֔וּת וַ/אֲשֶׁ֣ר בָּ/עִ֔יר רָעָ֥ב וָ/דֶ֖בֶר יֹאכֲלֶֽ/נּוּ", "en": {"kjv": "The sword is without, and the pestilence and the famine within: he that is in the field shall die with the sword; and he that is in the city, famine and pestilence shall devour him.", "web": "The sword is outside, and the pestilence and the famine within: he who is in the field shall die with the sword: and he who is in the city, famine and pestilence shall devour him.", "bsb": "The sword is outside; plague and famine are within. Those in the country will die by the sword, and those in the city will be devoured by famine and plague.", "asv": "The sword is without, and the pestilence and the famine within: he that is in the field shall die with the sword; and he that is in the city, famine and pestilence shall devour him.", "ylt": "The sword is without, And the pestilence and the famine within, He who is in a field by sword dieth, And he who is in a city, Famine and pestilence devour him.", "dra": "The sword without: and the pestilence, and the famine within: he that is in the field shall die by the sword: and they that are in the city, shall be devoured by the pestilence, and the famine.", "bbe": "Outside is the sword, and inside disease and need of food: he who is in the open country will be put to the sword; he who is in the town will come to his end through need of food and disease.", "geneva": "The sword is without, and the pestilence, and the famine within: he that is in the field, shall dye with the sword, and he that is in the citie, famine and pestilence shall deuoure him.", "wycliffe": "Swerd is with out forth, pestilence and hungur with ynne; he that is in the feeld, schal die bi swerd; and thei that ben in the citee, schulen be deuourid bi pestilence and hungur.", "rotherham": "The sword without, and Pestilence and famine within,— He that is in the field by the sword, shall die, and He that is in the city famine or pestilence shall devour him;", "darby": "The sword is without, and the pestilence and the famine within: he that is in the field shall die by the sword; and he that is in the city, famine and pestilence shall devour him.", "twenty": "", "jps": "The sword is without, and the pestilence and the famine within; he that is in the field shall die with the sword, and he that is in the city, famine and pestilence shall devour him.", "acv": "The sword is outside, and the pestilence and the famine inside. He who is in the field shall die with the sword, and he who is in the city, famine and pestilence shall devour him.", "anderson": "", "haweis": "", "noyes": "The sword is without, and pestilence and famine within; He that is in the field shall die by the sword; And he that is in the city, famine and pestilence shall devour him.", "webster": "The sword [is] without, and the pestilence and the famine within: he that [is] in the field shall die with the sword; and he that [is] in the city, famine and pestilence shall devour him.", "vulgate": "gladius foris pestis et fames intrinsecus qui in agro est gladio morietur et qui in civitate pestilentia et fame devorabuntur;", "brenton": "There shall be war with the sword without, and famine and pestilence within: he that is in the field shall die by the sword; and famine and pestilence shall destroy them that are in the city."}}, {"v": 16, "ref": "7:16", "o": "וּ/פָֽלְטוּ֙ פְּלִ֣יטֵי/הֶ֔ם וְ/הָי֣וּ אֶל הֶ/הָרִ֗ים כְּ/יוֹנֵ֧י הַ/גֵּאָי֛וֹת כֻּלָּ֖/ם הֹמ֑וֹת אִ֖ישׁ בַּ/עֲוֺנֽ/וֹ", "en": {"kjv": "But they that escape of them shall escape, and shall be on the mountains like doves of the valleys, all of them mourning, every one for his iniquity.", "web": "But those of those who escape shall escape, and shall be on the mountains like doves of the valleys, all of them moaning, every one in his iniquity.", "bsb": "The survivors will escape and live in the mountains, moaning like doves of the valley, each for his own iniquity.", "asv": "But those of them that escape shall escape, and shall be on the mountains like doves of the valleys, all of them moaning, every one in his iniquity.", "ylt": "And escaped away have their fugitives, And they have been on the mountains As doves of the valleys, All of them make a noising--each for his iniquity.", "dra": "And such of them as shall flee shall escape: and they shall be in the mountains like doves of the valleys, all of them trembling, every one for his iniquity.", "bbe": "And those of them who get away safely will go and be in the secret places like the doves of the valleys, all of them will come to death, every one in his sin.", "geneva": "But they that flee away from them, shall escape, and shalbe in the mountaines, like the doues of the valleis: all they shall mourne, euery one for his iniquitie.", "wycliffe": "And thei schulen be sauyd that fleen of hem; and thei schulen be as culueris of grete valeis in hillis, alle quakynge, ech man in his wickidnesse.", "rotherham": "While they who escape of them shall escape and become on the mountains as the doves of the valleys, all of them cooing,—each one in his punishment.", "darby": "And they that escape of them shall escape, and shall be on the mountains like doves of the valleys, all of them moaning, every one for his iniquity.", "twenty": "", "jps": "But they that shall at all escape of them, shall be on the mountains like doves of the valleys, all of them moaning, every one in his iniquity.", "acv": "But those of them who escape shall escape, and shall be on the mountains like doves of the valleys. All of them moaning, each one in his iniquity.", "anderson": "", "haweis": "", "noyes": "And those of them that escape shall be upon the mountains like doves of the valleys, All of them mourning, every one for his iniquity.", "webster": "But they that escape of them shall escape, and shall be on the mountains like doves of the valleys, all of them mourning, every one for his iniquity.", "vulgate": "et salvabuntur qui fugerint ex eis et erunt in montibus quasi columbae convallium omnes trepidi unusquisque in iniquitate sua;", "brenton": "But they that escape of them shall be delivered, and shall be upon the mountains: and I will slay all the rest, every one for his iniquities."}}, {"v": 17, "ref": "7:17", "o": "כָּל הַ/יָּדַ֖יִם תִּרְפֶּ֑ינָה וְ/כָל בִּרְכַּ֖יִם תֵּלַ֥כְנָה מָּֽיִם", "en": {"kjv": "All hands shall be feeble, and all knees shall be weak as water.", "web": "All hands shall be feeble, and all knees shall be weak as water.", "bsb": "Every hand will go limp, and every knee will turn to water.", "asv": "All hands shall be feeble, and all knees shall be weak as water.", "ylt": "All the hands are feeble, and all knees go--waters.", "dra": "All hands shall be made feeble, and all knees shall run with water.", "bbe": "All hands will be feeble and all knees without strength, like water.", "geneva": "All handes shalbe weake, and all knees shall fall away as water.", "wycliffe": "Alle hondis schulen be aclumsid, and alle knees schulen flowe with watris.", "rotherham": "All hands shall be unnerved; and All knees shall be weak as water,", "darby": "All hands shall be feeble, and all knees shall melt into water.", "twenty": "", "jps": "All hands shall be slack, and all knees shall drip with water.", "acv": "All hands shall be feeble, and all knees shall be weak as water.", "anderson": "", "haweis": "", "noyes": "All hands shall be feeble, And all knees shall flow with water.", "webster": "All hands shall be feeble, and all knees shall be weak [as] water.", "vulgate": "omnes manus dissolventur et omnia genua fluent aquis;", "brenton": "All hands shall be completely weakened, and all thighs shall be defiled with moisture."}}, {"v": 18, "ref": "7:18", "o": "וְ/חָגְר֣וּ שַׂקִּ֔ים וְ/כִסְּתָ֥ה אוֹתָ֖/ם פַּלָּצ֑וּת וְ/אֶ֤ל כָּל פָּנִים֙ בּוּשָׁ֔ה וּ/בְ/כָל רָאשֵׁי/הֶ֖ם קָרְחָֽה", "en": {"kjv": "They shall also gird themselves with sackcloth, and horror shall cover them; and shame shall be upon all faces, and baldness upon all their heads.", "web": "They shall also clothe themselves with sackcloth, and horror shall cover them; and shame shall be on all faces, and baldness on all their heads.", "bsb": "They will put on sackcloth, and terror will overwhelm them. Shame will cover all their faces, and all their heads will be shaved.", "asv": "They shall also gird themselves with sackcloth, and horror shall cover them; and shame shall be upon all faces, and baldness upon all their heads.", "ylt": "And they have girded on sackcloth, And covered them hath trembling, And unto all faces is shame, And on all their heads--baldness.", "dra": "And they shall gird themselves with haircloth, and fear shall cover them and shame shall be upon every face, and baldness upon all their heads.", "bbe": "And they will put haircloth round them, and deep fear will be covering them; and shame will be on all faces, and the hair gone from all their heads.", "geneva": "They shall also girde them selues with sackecloth, and feare shall couer them, and shame shalbe vpon all faces, and baldnes vpon their heads.", "wycliffe": "And thei schulen girde hem with heiris, and inward drede schal hile hem; and schenschipe schal be in ech face, and ballidnesse schal be in alle the heedis of hem.", "rotherham": "Therefore shall they gird themselves with sackcloth, And shuddering shall cover them,-And in all faces, shall be paleness, And in all their heads, baldness.", "darby": "And they shall gird on sackcloth, and horror shall cover them; and shame shall be upon all faces, and baldness upon all their heads.", "twenty": "", "jps": "They shall also gird themselves with sackcloth, and horror shall cover them; and shame shall be upon all faces, and baldness upon all their heads.", "acv": "They shall also gird themselves with sackcloth, and horror shall cover them. And shame shall be upon all faces, and baldness upon all their heads.", "anderson": "", "haweis": "", "noyes": "They shall also gird themselves with sackcloth, And horror shall cover them. And upon all their faces shall be shame, And upon all their heads baldness.", "webster": "They shall also gird [themselves] with sackcloth, and horror shall cover them; and shame [shall be] upon all faces, and baldness upon all their heads.", "vulgate": "et accingent se ciliciis et operiet eos formido et in omni facie confusio et in universis capitibus eorum calvitium;", "brenton": "And they shall gird themselves with sackcloth, and amazement shall cover them; and shame shall be upon them, even upon every face, and baldness upon every head."}}, {"v": 19, "ref": "7:19", "o": "כַּסְפָּ֞/ם בַּ/חוּצ֣וֹת יַשְׁלִ֗יכוּ וּ/זְהָבָ/ם֮ לְ/נִדָּ֣ה יִֽהְיֶה֒ כַּסְפָּ֨/ם וּ/זְהָבָ֜/ם לֹֽא יוּכַ֣ל לְ/הַצִּילָ֗/ם בְּ/יוֹם֙ עֶבְרַ֣ת יְהוָ֔ה נַפְשָׁ/ם֙ לֹ֣א יְשַׂבֵּ֔עוּ וּ/מֵעֵי/הֶ֖ם לֹ֣א יְמַלֵּ֑אוּ כִּֽי מִכְשׁ֥וֹל עֲוֺנָ֖/ם הָיָֽה", "en": {"kjv": "They shall cast their silver in the streets, and their gold shall be removed: their silver and their gold shall not be able to deliver them in the day of the wrath of the Lord: they shall not satisfy their souls, neither fill their bowels: because it is the stumblingblock of their iniquity.", "web": "They shall cast their silver in the streets, and their gold shall be as an unclean thing; their silver and their gold shall not be able to deliver them in the day of the wrath of Yahweh: they shall not satisfy their souls, neither fill their bowels; because it has been the stumbling block of their iniquity.", "bsb": "They will throw their silver into the streets, and their gold will seem unclean. Their silver and gold cannot save them in the day of the wrath of the LORD. They cannot satisfy their appetites or fill their stomachs with wealth, for it became the stumbling block that brought their iniquity.", "asv": "They shall cast their silver in the streets, and their gold shall be as an unclean thing; their silver and their gold shall not be able to deliver them in the day of the wrath of Jehovah: they shall not satisfy their souls, neither fill their bowels; because it hath been the stumblingblock of their iniquity.", "ylt": "Their silver into out-places they cast, And their gold impurity becometh. Their silver and their gold is not able to deliver them, In a day of the wrath of Jehovah, Their soul they do not satisfy, And their bowels they do not fill, For the stumbling-block of their iniquity it hath been.", "dra": "Their silver shall be cast forth, and their gold shall become a dunghill. Their silver and their gold shall not be able to deliver them in the day of the wrath of the Lord. They shall not satisfy their soul, and their bellies shall not be filled: because it hath been the stumblingblock of their iniquity.", "bbe": "They will put out their silver into the streets, and their gold will be as an unclean thing; their silver and their gold will not be able to keep them safe in the day of the wrath of the Lord; they will not get their desire or have food for their need: because it has been the cause of their falling into sin.", "geneva": "They shall cast their siluer in the streetes, and their golde shalbe cast farre off: their siluer and their gold can not deliuer them in the day of the wrath of the Lord: they shall not satisfie their soules, neither fill their bowels: for this ruine is for their iniquitie.", "wycliffe": "The siluer of hem schal be cast out, and the gold of hem schal be in to a dunghil; the siluer of hem and the gold of hem schal not mowe delyuere hem in the dai of the strong veniaunce of the Lord. Thei schulen not fille her soule, and the wombis of hem schulen not be fillid; for it is maad the sclaundre of hir wickidnesse.", "rotherham": "Their silver into the streets, shall they cast and Their gold for throwing away, shall serve, Their silver and their gold shall not be able to deliver them in the day of the wrath of Yahweh, Their craving, shall they not satisfy, and Their belly, shall they not fill, For a stumbling-block, hath their iniquity become.", "darby": "They shall cast their silver in the streets, and their gold shall be as an impurity: their silver and their gold shall not be able to deliver them in the day of Jehovah's wrath; they shall not satisfy their souls, neither fill their belly; for it hath been the stumbling-block of their iniquity.", "twenty": "", "jps": "They shall cast their silver in the streets, and their gold shall be as an unclean thing; their silver and their gold shall not be able to deliver them in the day of the wrath of HaShem; they shall not satisfy their souls, neither fill their bowels; because it hath been the stumblingblock of their iniquity.", "acv": "They shall cast their silver in the streets, and their gold shall be as an unclean thing. Their silver and their gold shall not be able to deliver them in the day of the wrath of Jehovah. They shall not satisfy their souls, nor fill their bowels, because it has been the stumbling block of their iniquity.", "anderson": "", "haweis": "", "noyes": "Their silver shall they cast into the streets, And their gold shall be as an unclean thing. Their silver and their gold shall not be able to deliver them In the day of the wrath of Jehovah; Their hunger shall not be satisfied, Nor their body filled with it; For it was the stumbling-block of their iniquity.", "webster": "They shall cast their silver in the streets, and their gold shall be removed: their silver and their gold shall not be able to deliver them in the day of the wrath of the LORD: they shall not satisfy their souls, neither fill their bowels because it is the stumbling-block of their iniquity.", "vulgate": "argentum eorum foris proicietur et aurum eorum in sterquilinium erit argentum eorum et aurum eorum non valebit liberare eos in die furoris Domini animam suam non saturabunt et ventres eorum non implebuntur quia scandalum iniquitatis eorum factum est;", "brenton": "Their silver shall be cast forth in the streets, and their gold shall be despised: their souls shall not be satisfied, and their bellies shall not be filled: for it was the punishment of their iniquities."}}, {"v": 20, "ref": "7:20", "o": "וּ/צְבִ֤י עֶדְי/וֹ֙ לְ/גָא֣וֹן שָׂמָ֔/הוּ וְ/צַלְמֵ֧י תוֹעֲבֹתָ֛/ם שִׁקּוּצֵי/הֶ֖ם עָ֣שׂוּ ב֑/וֹ עַל כֵּ֛ן נְתַתִּ֥י/ו לָ/הֶ֖ם לְ/נִדָּֽה", "en": {"kjv": "As for the beauty of his ornament, he set it in majesty: but they made the images of their abominations and of their detestable things therein: therefore have I set it far from them.", "web": "As for the beauty of his ornament, he set it in majesty; but they made the images of their abominations and their detestable things therein: therefore have I made it to them as an unclean thing.", "bsb": "His beautiful ornaments they transformed into pride and used them to fashion their vile images and detestable idols. Therefore I will make these into something unclean for them.", "asv": "As for the beauty of his ornament, he set it in majesty; but they made the images of their abominations and their detestable things therein: therefore have I made it unto them as an unclean thing.", "ylt": "As to the beauty of his ornament, For excellency He set it, And the images of their abominations, Their detestable things--they made in it, Therefore I have given it to them for impurity,", "dra": "And they have turned the ornament of their jewels into pride, and have made of it the images of their abominations, and idols: therefore I have made it an uncleanness to them.", "bbe": "As for their beautiful ornament, they had put it on high, and had made the images of their disgusting and hated things in it: for this cause I have made it an unclean thing to them.", "geneva": "He had also set the beautie of his ornament in maiestie: but they made images of their abominations, and of their idoles therein: therefore haue I set it farre from them.", "wycliffe": "And thei setteden the ournement of her brochis in to pride; and thei maden of it the ymagis of her abhomynaciouns and simylacris. For this thing Y yaf it to hem, in to vnclennesse.", "rotherham": "When, the beauty of his own ornament, he had, in majesty, placed, Then, the images, of their abominations Their detestable things, Made they therein,— For this cause have I delivered it up to them for removal;", "darby": "And he set in majesty his beautiful ornament; but they made therein the images of their abominations [and] of their detestable things: therefore have I made it an impurity unto them.", "twenty": "", "jps": "And as for the beauty of their ornament, which was set for a pride, they made the images of their abominations and their detestable things thereof; therefore have I made it unto them as an unclean thing.", "acv": "As for the beauty of his ornament, he set it in majesty, but they made the images of their abominations, and their detestable things in it. Therefore I have made it as an unclean thing to them.", "anderson": "", "haweis": "", "noyes": "For the beauty of their ornaments they turned into pride, And the images of their abominations and of their detestable things they made with it; Therefore will I make it to them as an unclean thing.", "webster": "As for the beauty of his ornament, he set it in majesty: but they made the images of their abominations [and] of their detestable things therein: therefore have I set it far from them.", "vulgate": "et ornamentum monilium suorum in superbiam posuerunt et imagines abominationum suarum et simulacrorum fecerunt ex eo propter hoc dedi eis illud in inmunditiam;", "brenton": "As for their choice ornaments, they employed them for pride, and they made of them images of their abominations: therefore have I made them uncleanness to them."}}, {"v": 21, "ref": "7:21", "o": "וּ/נְתַתִּ֤י/ו בְּ/יַֽד הַ/זָּרִים֙ לָ/בַ֔ז וּ/לְ/רִשְׁעֵ֥י הָ/אָ֖רֶץ לְ/שָׁלָ֑ל ו/חלל/ה וְ/חִלְּלֽוּ/הוּ", "en": {"kjv": "And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil; and they shall pollute it.", "web": "I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a plunder; and they shall profane it.", "bsb": "And I will hand these things over as plunder to foreigners and loot to the wicked of the earth, who will defile them.", "asv": "And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil; and they shall profane it.", "ylt": "And I have given it into the hand of the strangers for a prey, And to the wicked of the land for a spoil, And they have polluted it.", "dra": "And I will give it into the hands of strangers for spoil, and to the wicked of the earth for a prey, and they shall defile it.", "bbe": "And I will give it into the hands of men from strange lands who will take it by force, and to the evil-doers of the earth to have for themselves; and they will make it unholy.", "geneva": "And I will giue it into the handes of the strangers to be spoyled, and to the wicked of the earth to be robbed, and they shall pollute it.", "wycliffe": "And Y schal yyue it in to the hondis of aliens, to rauysche, and to the vnpitouse men of erthe, in to prey, and thei schulen defoule it.", "rotherham": "Yea I will deliver it Into the hand of foreigners for a prey, And to the lawless ones of the earth for a spoil, And they will profane it;", "darby": "And I will give it into the hands of strangers for a prey, and to the wicked of the earth for a spoil; and they shall profane it.", "twenty": "", "jps": "And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil; and they shall profane it.", "acv": "And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil, and they shall profane it.", "anderson": "", "haweis": "", "noyes": "And I will give it into the hands of strangers for a prey, And to the wicked of the earth for a spoil, And they shall pollute it.", "webster": "And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil; and they shall pollute it.", "vulgate": "et dabo illud in manus alienorum ad diripiendum et impiis terrae in praedam et contaminabunt illud;", "brenton": "And I will deliver them into the hands of strangers to make them a prey, and to the pests of the earth for a spoil; and they shall profane them."}}, {"v": 22, "ref": "7:22", "o": "וַ/הֲסִבּוֹתִ֤י פָנַ/י֙ מֵ/הֶ֔ם וְ/חִלְּל֖וּ אֶת צְפוּנִ֑/י וּ/בָאוּ בָ֥/הּ פָּרִיצִ֖ים וְ/חִלְּלֽוּ/הָ", "en": {"kjv": "My face will I turn also from them, and they shall pollute my secret place: for the robbers shall enter into it, and defile it.", "web": "My face will I turn also from them, and they shall profane my secret place; and robbers shall enter into it, and profane it.", "bsb": "I will turn My face away from them, and they will defile My treasured place. Violent men will enter it, and they will defile it.", "asv": "My face will I turn also from them, and they shall profane my secret place; and robbers shall enter into it, and profane it.", "ylt": "And I have turned My face from them, And they have polluted My hidden place, Yea, come into it have destroyers, and polluted it.", "dra": "And I will turn away my face from them, and they shall violate my secret place: and robbers shall enter into it, and defile it.", "bbe": "And my face will be turned away from them, and they will make my secret place unholy: violent men will go into it and make it unholy.", "geneva": "My face will I turne also from them, and they shall pollute my secret place: for the destroyers shall enter into it, and defile it.", "wycliffe": "And Y schal turne awei my face fro hem, and thei schulen defoule my priuyte; and harlotis schulen entre in to it, and schulen defoule it.", "rotherham": "And I will turn away my face from them, And they will profane my cherished place,—Yea there will enter it violent men Who will profane it.", "darby": "And I will turn my face from them; and they shall profane my secret [place]; and the violent shall enter into it, and profane it.", "twenty": "", "jps": "I will also turn My face from them, and they shall profane My secret place; and robbers shall enter into it, and profane it.", "acv": "I will also turn my face from them, and they shall profane my secluded place. And robbers shall enter into it, and profane it.", "anderson": "", "haweis": "", "noyes": "And I will turn my face from them, So that my secret place shall be polluted; Robbers shall enter into it, and pollute it.", "webster": "My face will I turn also from them, and they shall pollute my secret [place]: for the robbers shall enter into it, and defile it.", "vulgate": "et avertam faciem meam ab eis et violabunt arcanum meum et introibunt in illud emissarii et contaminabunt illud;", "brenton": "And I will turn away my face from them, and they shall defile my charge, and shall go in to them unguardedly, and profane them."}}, {"v": 23, "ref": "7:23", "o": "עֲשֵׂ֖ה הָֽ/רַתּ֑וֹק כִּ֣י הָ/אָ֗רֶץ מָֽלְאָה֙ מִשְׁפַּ֣ט דָּמִ֔ים וְ/הָ/עִ֖יר מָלְאָ֥ה חָמָֽס", "en": {"kjv": "Make a chain: for the land is full of bloody crimes, and the city is full of violence.", "web": "Make the chain; for the land is full of bloody crimes, and the city is full of violence.", "bsb": "Forge the chain, for the land is full of crimes of bloodshed, and the city is full of violence.", "asv": "Make the chain; for the land is full of bloody crimes, and the city is full of violence.", "ylt": "Make the chain; for the land Hath been full of bloody judgments, And the city hath been full of violence.", "dra": "Make a shutting up: for the land is full of the judgment of blood, and the city is full of iniquity.", "bbe": "Make the chain: for the land is full of crimes of blood, and the town is full of violent acts.", "geneva": "Make a chaine: for the lande is full of the iudgement of blood, and the citie is full of crueltie.", "wycliffe": "Make thou a closyng to gidere; for the lond is ful of doom of bloodis, and the citee is ful of wickidnesse.", "rotherham": "Prepare thou a chain,— For, the land, is full of the crime of bloodshed, And, the city, is full of violence.", "darby": "Make the chain; for the land is full of bloody crimes, and the city is full of violence.", "twenty": "", "jps": "Make the chain; for the land is full of bloody crimes, and the city is full of violence.", "acv": "Make the chain, for the land is full of bloody crimes, and the city is full of violence.", "anderson": "", "haweis": "", "noyes": "Make a chain! For the land is full of blood-guiltiness, And the city is full of violence.", "webster": "Make a chain: for the land is full of bloody crimes, and the city is full of violence.", "vulgate": "fac conclusionem quoniam terra plena est iudicio sanguinum et civitas plena iniquitate;", "brenton": "And they shall work uncleanness: because the land is full of strange nations, and the city is full of iniquity."}}, {"v": 24, "ref": "7:24", "o": "וְ/הֵֽבֵאתִי֙ רָעֵ֣י גוֹיִ֔ם וְ/יָרְשׁ֖וּ אֶת בָּֽתֵּי/הֶ֑ם וְ/הִשְׁבַּתִּי֙ גְּא֣וֹן עַזִּ֔ים וְ/נִחֲל֖וּ מְקַֽדְשֵׁי/הֶֽם", "en": {"kjv": "Wherefore I will bring the worst of the heathen, and they shall possess their houses: I will also make the pomp of the strong to cease; and their holy places shall be defiled.", "web": "Therefore I will bring the worst of the nations, and they shall possess their houses: I will also make the pride of the strong to cease; and their holy places shall be profaned.", "bsb": "So I will bring the most wicked of nations to take possession of their houses. I will end the pride of the mighty, and their holy places will be profaned.", "asv": "Wherefore I will bring the worst of the nations, and they shall possess their houses: I will also make the pride of the strong to cease; and their holy places shall be profaned.", "ylt": "And I have brought in the wicked of the nations, And they have possessed their houses, And I have caused to cease the excellency of the strong, And polluted have been those sanctifying them.", "dra": "And I will bring the worst of the nations, and they shall possess their houses: and I will make the pride of the mighty to cease, and they shall possess their sanctuary.", "bbe": "For this reason I will send the worst of the nations and they will take their houses for themselves: I will make the pride of their strength come to an end; and their holy places will be made unclean.", "geneva": "Wherefore I will bring the most wicked of the heathen, and they shall possesse their houses: I will also make the pompe of the mightie to cease, and their holie places shalbe defiled.", "wycliffe": "And Y schal brynge the worste of hethene men, and thei schulen haue in possessioun the housis of hem; and Y schal make the pride of miyti men to ceesse, and enemyes schulen haue in possessioun the seyntuaries of hem.", "rotherham": "So then I will bring in the wicked ones of the nations, And they shall take possession of their houses,—And I will cause to cease the pomp of the strong ones, And their holy places shall be profaned.", "darby": "Therefore will I bring the worst of the nations, and they shall possess their houses; and I will make the pride of the strong to cease; and their sanctuaries shall be profaned.", "twenty": "", "jps": "Wherefore I will bring the worst of the nations, and they shall possess their houses; I will also make the pride of the strong to cease; and their holy places shall be profaned.", "acv": "Therefore I will bring the worst of the nations, and they shall possess their houses. I will also make the pride of the strong to cease, and their holy places shall be profaned.", "anderson": "", "haweis": "", "noyes": "Therefore will I bring the most cruel among the nations, And they shall possess your houses; I will also make the pride of the strong to cease, And their holy places shall be defiled.", "webster": "Wherefore I will bring the worst of the heathen, and they shall possess their houses: I will also make the pomp of the strong to cease, and their holy places shall be defiled.", "vulgate": "et adducam pessimos de gentibus et possidebunt domos eorum et quiescere faciam superbiam potentium et possidebunt sanctuaria eorum;", "brenton": "And I will turn back the boasting of their strength; and their holy things shall be defiled."}}, {"v": 25, "ref": "7:25", "o": "קְפָ֖דָה בָ֑א וּ/בִקְשׁ֥וּ שָׁל֖וֹם וָ/אָֽיִן", "en": {"kjv": "Destruction cometh; and they shall seek peace, and there shall be none.", "web": "Destruction comes; and they shall seek peace, and there shall be none.", "bsb": "Anguish is coming! They will seek peace, but find none.", "asv": "Destruction cometh; and they shall seek peace, and there shall be none.", "ylt": "Destruction hath come, And they have sought peace, and there is none.", "dra": "When distress cometh upon them, they will seek for peace and there shall be none.", "bbe": "Shaking fear is coming; and they will be looking for peace, and there will be no peace.", "geneva": "When destruction commeth, they shall seeke peace, and shall not haue it.", "wycliffe": "In anguysch comynge aboue thei schulen seke pees, and it schal not be.", "rotherham": "Destruction, hath entered,- And they shall seek welfare and there be none.", "darby": "Destruction cometh; and they shall seek peace, but there shall be none.", "twenty": "", "jps": "Horror cometh; and they shall seek peace, and there shall be none.", "acv": "Destruction comes. And they shall seek peace, and there shall be none.", "anderson": "", "haweis": "", "noyes": "Destruction cometh; And they shall seek peace, and not find it.", "webster": "Destruction cometh; and they shall seek peace, and [there shall be] none.", "vulgate": "angustia superveniente requirent pacem et non erit;", "brenton": "And though propitiation shall come, and one shall seek peace, yet there shall be none."}}, {"v": 26, "ref": "7:26", "o": "הֹוָ֤ה עַל הֹוָה֙ תָּב֔וֹא וּ/שְׁמֻעָ֥ה אֶל שְׁמוּעָ֖ה תִּֽהְיֶ֑ה וּ/בִקְשׁ֤וּ חָזוֹן֙ מִ/נָּבִ֔יא וְ/תוֹרָה֙ תֹּאבַ֣ד מִ/כֹּהֵ֔ן וְ/עֵצָ֖ה מִ/זְּקֵנִֽים", "en": {"kjv": "Mischief shall come upon mischief, and rumour shall be upon rumour; then shall they seek a vision of the prophet; but the law shall perish from the priest, and counsel from the ancients.", "web": "Mischief shall come on mischief, and rumor shall be on rumor; and they shall seek a vision of the prophet; but the law shall perish from the priest, and counsel from the elders.", "bsb": "Disaster upon disaster will come, and rumor after rumor. Then they will seek a vision from a prophet, but instruction from the priests will perish, as will counsel from the elders.", "asv": "Mischief shall come upon mischief, and rumor shall be upon rumor; and they shall seek a vision of the prophet; but the law shall perish from the priest, and counsel from the elders.", "ylt": "Mischief on mischief cometh, and report is on report, And they have sought a vision from a prophet, And law doth perish from the priest, And counsel from the elders,", "dra": "Trouble shall come upon trouble, and rumour upon rumour, and they shall seek a vision of the prophet, and the law shall perish from the priest, and counsel from the ancients.", "bbe": "Destruction will come on destruction, and one story after another; and the vision of the prophet will be shamed, and knowledge of the law will come to an end among the priests, and wisdom among the old.", "geneva": "Calamitie shall come vpon calamitie, and rumour shall bee vpon rumour: then shall they seeke a vision of the Prophet: but the Lawe shall perish from the Priest, and counsel from the Ancient.", "wycliffe": "Disturblyng schal come on disturblyng, and heryng on heryng; and thei schulen seke of the profete a reuelacioun, and lawe shal perische fro the preest, and counsel fro eldre men.", "rotherham": "Disaster upon disaster, shall come, And report after report shall arise, Therefore shall they seek a vision from prophet, And law shall perish from priest. And counsel from elders.", "darby": "Mischief shall come upon mischief, and rumour shall be upon rumour; and they shall seek a vision from a prophet; but the law shall perish from the priest, and counsel from the elders.", "twenty": "", "jps": "Calamity shall come upon calamity, and rumour shall be upon rumour; and they shall seek a vision of the prophet, and instruction shall perish from the priest, and counsel from the elders.", "acv": "Mischief shall come upon mischief, and rumor shall be upon rumor. And they shall seek a vision of the prophet, but the law shall perish from the priest, and counsel from the elders.", "anderson": "", "haweis": "", "noyes": "Calamity shall come upon calamity, And rumor shall be upon rumor; And they shall seek a vision from the prophet in vain; Instruction shall perish from the priests, And counsel from the elders.", "webster": "Mischief shall come upon mischief, and rumor shall be upon rumor; then shall they seek a vision of the prophet; but the law shall perish from the priest, and counsel from the elders.", "vulgate": "conturbatio super conturbationem veniet et auditus super auditum et quaerent visionem de propheta et lex peribit a sacerdote et consilium a senioribus;", "brenton": "There shall be woe upon woe, and there shall be message upon message; and a vision shall be sought from a prophet; but the law shall perish from the priest, and counsel from the elders."}}, {"v": 27, "ref": "7:27", "o": "הַ/מֶּ֣לֶךְ יִתְאַבָּ֗ל וְ/נָשִׂיא֙ יִלְבַּ֣שׁ שְׁמָמָ֔ה וִ/ידֵ֥י עַם הָ/אָ֖רֶץ תִּבָּהַ֑לְנָה מִ/דַּרְכָּ֞/ם אֶעֱשֶׂ֤ה אוֹתָ/ם֙ וּ/בְ/מִשְׁפְּטֵי/הֶ֣ם אֶשְׁפְּטֵ֔/ם וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "The king shall mourn, and the prince shall be clothed with desolation, and the hands of the people of the land shall be troubled: I will do unto them after their way, and according to their deserts will I judge them; and they shall know that I am the Lord.", "web": "The king shall mourn, and the prince shall be clothed with desolation, and the hands of the people of the land shall be troubled: I will do to them after their way, and according to their own judgments will I judge them; and they shall know that I am Yahweh.", "bsb": "The king will mourn, the prince will be clothed with despair, and the hands of the people of the land will tremble. I will deal with them according to their conduct, and I will judge them by their own standards. Then they will know that I am the LORD.’”", "asv": "The king shall mourn, and the prince shall be clothed with desolation, and the hands of the people of the land shall be troubled: I will do unto them after their way, and according to their deserts will I judge them; and they shall know that I am Jehovah.", "ylt": "The king doth become a mourner, And a prince putteth on desolation, And the hands of the people of the land are troubled, From their own way I deal with them, And with their own judgments I judge them, And they have known that I am Jehovah!'", "dra": "The king shall mourn, and the prince shall be clothed with sorrow, and the hands of the people of the land shall be troubled. I will do to them according to their way, and will judge them according to their judgments: and they shall know that I am the Lord.", "bbe": "The king will give himself up to sorrow, and the ruler will be clothed with wonder, and the hands of the people of the land will be troubled: I will give them punishment for their ways, judging them as it is right for them to be judged; and they will be certain that I am the Lord.", "geneva": "The King shall mourne, and the prince shall be clothed with desolation, and the handes of the people in the land shall be troubled: I wil doe vnto them according to their waies, and according to their iudgements will I iudge them, and they shall knowe that I am the Lord.", "wycliffe": "The kyng schal mourne, and the prince schal be clothid in weilyng, and the hondis of the puple of the lond schulen be disturblid; bi the weie of hem Y schal do to hem, and bi the domes of hem Y schal deme hem; and thei schulen wite, that Y am the Lord.", "rotherham": "The king, shall mourn and, The chief, shall clothe himself with astonishment, and, the hands of the people of the land, shall be wrung in anguish,— After their own way, will I deal with them and, With their own sentences, will I sentence them, And they shall know that, I, am Yahweh.", "darby": "The king shall mourn, and the prince shall be clothed with dismay, and the hands of the people of the land shall tremble: I will do unto them according to their way, and with their judgments will I judge them; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "The king shall mourn, and the prince shall be clothed with appalment, and the hands of the people of the land shall be enfeebled; I will do unto them after their way, and according to their deserts will I judge them; and they shall know that I am HaShem.'", "acv": "The king shall mourn, and the ruler shall be clothed with desolation, and the hands of the people of the land shall be troubled. I will do to them according to their way, and according to their deserts I will judge them. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "The king shall mourn, And the prince shall be clothed with amazement; And the hands of the people of the land shall be troubled. I will do to them according to their way, and according to their deserts will I judge them, And they shall know that I am Jehovah.", "webster": "The king shall mourn, and the prince shall be clothed with desolation, and the hands of the people of the land shall be troubled: I will do to them after their way, and according to their deserts will I judge them, and they shall know that I [am] the LORD.", "vulgate": "rex lugebit et princeps induetur maerore et manus populi terrae conturbabuntur secundum viam eorum faciam eis et secundum iudicia eorum iudicabo eos et scient quia ego Dominus;", "brenton": "The prince shall clothe himself with desolation, and the hands of the people of the land shall be made feeble: I will do to them according to their ways, and according to their judgments will I punish them; and they shall know that I am the Lord."}}]}, {"c": 8, "verses": [{"v": 1, "ref": "8:1", "o": "וַ/יְהִ֣י בַּ/שָּׁנָ֣ה הַ/שִּׁשִּׁ֗ית בַּ/שִּׁשִּׁי֙ בַּ/חֲמִשָּׁ֣ה לַ/חֹ֔דֶשׁ אֲנִי֙ יוֹשֵׁ֣ב בְּ/בֵיתִ֔/י וְ/זִקְנֵ֥י יְהוּדָ֖ה יוֹשְׁבִ֣ים לְ/פָנָ֑/י וַ/תִּפֹּ֤ל עָלַ/י֙ שָׁ֔ם יַ֖ד אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "And it came to pass in the sixth year, in the sixth month, in the fifth day of the month, as I sat in mine house, and the elders of Judah sat before me, that the hand of the Lord God fell there upon me.", "web": "In the sixth year, in the sixth month, in the fifth day of the month, as I sat in my house, and the elders of Judah sat before me, the Lord Yahweh’s hand fell there on me.", "bsb": "In the sixth year, on the fifth day of the sixth month, I was sitting in my house, and the elders of Judah were sitting before me; and there the hand of the Lord GOD fell upon me.", "asv": "And it came to pass in the sixth year, in the sixthmonth, in the fifthdayof the month, as I sat in my house, and the elders of Judah sat before me, that the hand of the Lord Jehovah fell there upon me.", "ylt": "And it cometh to pass, in the sixth year, in the sixth month , in the fifth of the month, I am sitting in my house, and elders of Judah are sitting before me, and fall on me there doth a hand of the Lord Jehovah,", "dra": "And it came to pass in the sixth year, in the sixth month, in the fifth day of the month, as I sat in my house, and the ancients of Juda sat before me, that the hand of the Lord God fell there upon me.", "bbe": "Now in the sixth year, in the sixth month, on the fifth day of the month, when I was in my house and the responsible men of Judah were seated before me, the hand of the Lord came on me there.", "geneva": "And in the sixt yere, in the sixt moneth, and in the fift day of the moneth, as I sate in mine house, and the Elders of Iudah sate before me, the hand of the Lord God fell there vpon me.", "wycliffe": "And it was doon in the sixte yeer, in the sixte monethe, in the fyuethe dai of the monethe, Y sat in myn hous, and the elde men of Juda saten bifore me; and the hond of the Lord God felle there on me.", "rotherham": "And it came to pass, in the sixth year in the sixth month, on the fifth of the month, I being seated in my house, and the elders of Judah being seated before me, then fell upon me there the hand of My Lord Yahweh.", "darby": "And it came to pass in the sixth year, in the sixth [month], on the fifth of the month, that [as] I sat in my house, and the elders of Judah sat before me, the hand of the Lord Jehovah fell there upon me.", "twenty": "", "jps": "And it came to pass in the sixth year, in the sixth month, in the fifth day of the month, as I sat in my house, and the elders of Judah sat before me, that the hand of the L-rd GOD fell there upon me.", "acv": "And it came to pass in the sixth year, in the sixth month, in the fifth day of the month, as I sat in my house, and the elders of Judah sat before me, that the hand of the lord Jehovah fell there upon me.", "anderson": "", "haweis": "", "noyes": "Now it came to pass in the sixth year, in the sixth month, on the fifth day of the month, as I sat in my house, and the elders of Judah sat before me, that the hand of the Lord Jehovah fell there upon me.", "webster": "And it came to pass in the sixth year, in the sixth [month], in the fifth [day] of the month, [as] I sat in my house, and the elders of Judah sat before me, that the hand of the Lord GOD fell there upon me.", "vulgate": "et factum est in anno sexto in sexto mense in quinta mensis ego sedebam in domo mea et senes Iuda sedebant coram me et cecidit super me ibi manus Domini Dei;", "brenton": "And it came to pass in the sixth year, in the fifth month, on the fifth day of the month, I was sitting in the house, and the elders of Juda were sitting before me: and the hand of the Lord came upon me."}}, {"v": 2, "ref": "8:2", "o": "וָ/אֶרְאֶ֗ה וְ/הִנֵּ֤ה דְמוּת֙ כְּ/מַרְאֵה אֵ֔שׁ מִ/מַּרְאֵ֥ה מָתְנָ֛י/ו וּ/לְ/מַ֖טָּה אֵ֑שׁ וּ/מִ/מָּתְנָ֣י/ו וּ/לְ/מַ֔עְלָ/ה כְּ/מַרְאֵה זֹ֖הַר כְּ/עֵ֥ין הַ/חַשְׁמַֽלָ/ה", "en": {"kjv": "Then I beheld, and lo a likeness as the appearance of fire: from the appearance of his loins even downward, fire; and from his loins even upward, as the appearance of brightness, as the colour of amber.", "web": "Then I saw, and behold, a likeness as the appearance of fire; from the appearance of his waist and downward, fire; and from his waist and upward, as the appearance of brightness, as it were glowing metal.", "bsb": "Then I looked and saw a figure like that of a man. From His waist down His appearance was like fire, and from His waist up He was as bright as the gleam of amber.", "asv": "Then I beheld, and, lo, a likeness as the appearance of fire; from the appearance of his loins and downward, fire; and from his loins and upward, as the appearance of brightness, as it were glowing metal.", "ylt": "and I look, and lo, a likeness as the appearance of fire, from the appearance of His loins and downward--fire, and from His loins and upward, as the appearance of brightness, as the colour of copper.", "dra": "And I saw, and behold a likeness as the appearance of fire: from the appearance of his loins, and downward, fire: and from his loins, and upward, as the appearance of brightness, as the appearance of amber.", "bbe": "And looking, I saw a form like fire; from the middle of his body and down there was fire: and up from the middle of his body a sort of shining, like electrum.", "geneva": "Then I beheld, and lo, there was a likenesse, as the appearance of fire, to looke to, from his loynes downeward, and from his loynes vpward, as the appearance of brightnes, and like vnto amber.", "wycliffe": "And Y siy, and lo! a licnesse as the biholdyng of fier; fro the biholding of hise leendis and bynethe was fier, and fro hise leendis and aboue was as the biholdyng of schynyng, as the siyt of electre.", "rotherham": "So I looked, and lo! a likeness as the appearance of a man, from the appearance of his loins and downward fire, and from his loins and upwards as an appearance of shining, as the look of amber,", "darby": "And I looked, and behold, a likeness as the appearance of fire; from the appearance of his loins and downward, fire; and from his loins and upward, as the appearance of brightness, as the look of glowing brass.", "twenty": "", "jps": "Then I beheld, and lo a likeness as the appearance of fire: from the appearance of his loins and downward, fire; and from his loins and upward, as the appearance of brightness, as the colour of electrum.", "acv": "Then I beheld, and, lo, a likeness as the appearance of fire, from the appearance of his loins and downward, fire, and from his loins and upward, as the appearance of brightness, as it were glowing metal.", "anderson": "", "haweis": "", "noyes": "And I looked, and lo, a form having the appearance of fire; from the appearance of his loins downward, of fire; and from his loins upward, of a bright light, like the splendor of shining brass.", "webster": "Then I beheld, and lo a likeness as the appearance of fire: from the appearance of his loins even downward, fire; and from his loins even upward, as the appearance of brightness, as the color of amber.", "vulgate": "et vidi et ecce similitudo quasi aspectus ignis ab aspectu lumborum eius et deorsum ignis et a lumbis eius et sursum quasi aspectus splendoris ut visio electri;", "brenton": "And I looked, and, behold, the likeness of a man: from his loins and downwards there was fire, and from his loins upwards there was as the appearance of amber."}}, {"v": 3, "ref": "8:3", "o": "וַ/יִּשְׁלַח֙ תַּבְנִ֣ית יָ֔ד וַ/יִּקָּחֵ֖/נִי בְּ/צִיצִ֣ת רֹאשִׁ֑/י וַ/תִּשָּׂ֣א אֹתִ֣/י ר֣וּחַ בֵּֽין הָ/אָ֣רֶץ וּ/בֵ֣ין הַ/שָּׁמַ֡יִם וַ/תָּבֵא֩ אֹתִ֨/י יְרוּשָׁלְַ֜מָ/ה בְּ/מַרְא֣וֹת אֱלֹהִ֗ים אֶל פֶּ֜תַח שַׁ֤עַר הַ/פְּנִימִית֙ הַ/פּוֹנֶ֣ה צָפ֔וֹנָ/ה אֲשֶׁר שָׁ֣ם מוֹשַׁ֔ב סֵ֖מֶל הַ/קִּנְאָ֥ה הַ/מַּקְנֶֽה", "en": {"kjv": "And he put forth the form of an hand, and took me by a lock of mine head; and the spirit lifted me up between the earth and the heaven, and brought me in the visions of God to Jerusalem, to the door of the inner gate that looketh toward the north; where was the seat of the image of jealousy, which provoketh to jealousy.", "web": "He stretched out the form of a hand, and took me by a lock of my head; and the Spirit lifted me up between earth and the sky, and brought me in the visions of God to Jerusalem, to the door of the gate of the inner court that looks toward the north; where there was the seat of the image of jealousy, which provokes to jealousy.", "bsb": "He stretched out what looked like a hand and took me by the hair of my head. Then the Spirit lifted me up between earth and heaven and carried me in visions of God to Jerusalem, to the entrance of the north gate of the inner court, where the idol that provokes jealousy was seated.", "asv": "And he put forth the form of a hand, and took me by a lock of my head; and the Spirit lifted me up between earth and heaven, and brought me in the visions of God to Jerusalem, to the door of the gate of the inner court that looketh toward the north; where was the seat of the image of jealousy, which provoketh to jealousy.", "ylt": "And He putteth forth a form of a hand, and taketh me by a lock of my head, and lift me up doth a spirit between the earth and the heavens, and it bringeth me in to Jerusalem in visions of God, unto the opening of the inner gate that is facing the north, where is the seat of the figure of jealousy that is making jealous,", "dra": "And the likeness of a hand was put forth and took me by a lock of my head: and the spirit lifted me up between the earth and the heaven, and brought me in the vision of God into Jerusalem, near the inner gate, that looked toward the north, where was set the idol of jealousy to provoke to jealousy.", "bbe": "And he put out the form of a hand and took me by the hair of my head; and the wind, lifting me up between the earth and the heaven, took me in the visions of God to Jerusalem, to the way into the inner door facing to the north; where was the seat of the image of envy.", "geneva": "And he stretched out the likenes of an had, and tooke me by an hearie locke of mine head, and the Spirit lift me vp betweene the earth, and the heauen, and brought mee by a Diuine vision to Ierusalem, into the entry of ye inner gate that lieth toward the North, where remained the idole of indignation, which prouoked indignation.", "wycliffe": "And the licnesse of an hond was sent out, and took me bi the heer of myn heed; and the spirit reiside me bitwixe heuene and erthe, and brouyte me in to Jerusalem, in the siyt of God, bisidis the ynnere dore that bihelde to the north, where the idol of enuye was set, to stire indignacioun.", "rotherham": "Then put he forth the similitude of a hand, and took me by the forelock of my head,—and the Spirit lifted me up between the earth and the heavens and brought me to Jerusalem in the visions of God into the opening of the inner gate that looketh toward the north, where was the seat of the Statue of Jealousy. that provoketh to jealousy;", "darby": "And he stretched forth the form of a hand, and took me by a lock of my head; and the Spirit lifted me up between the earth and the heavens, and brought me in the visions ofGod to Jerusalem, to the entry of the inner gate that looketh toward the north, where was the seat of the image of jealousy, which provoketh to jealousy.", "twenty": "", "jps": "And the form of a hand was put forth, and I was taken by a lock of my head; and a spirit lifted me up between the earth and the heaven, and brought me in the visions of G-d to Jerusalem, to the door of the gate of the inner court that looketh toward the north; where was the seat of the image of jealousy, which provoketh to jealousy.", "acv": "And he put forth the form of a hand, and took me by a lock of my head. And the Spirit lifted me up between earth and heaven, and brought me in the visions of God to Jerusalem, to the door of the gate of the inner court that looks toward the north, where the seat of the image of jealousy was, which provokes to jealousy.", "anderson": "", "haweis": "", "noyes": "And he put forth the form of a hand, and took me by a lock of my head. And the spirit lifted me up between the earth and the heaven, and brought me, in the visions of God, to Jerusalem, to the door of the inner gate, that looketh toward the north, where stood the idol of jealousy, which provoketh to jealousy.", "webster": "And he put forth the form of a hand, and took me by a lock of my head; and the spirit lifted me up between the earth and the heaven, and brought me in the visions of God to Jerusalem, to the door of the inner gate that looketh towards the north; where [was] the seat of the image of jealousy, which provoketh to jealousy.", "vulgate": "et emissa similitudo manus adprehendit me in cincinno capitis mei et elevavit me spiritus inter terram et caelum et adduxit in Hierusalem in visione Dei iuxta ostium interius quod respiciebat aquilonem ubi erat statutum idolum zeli ad provocandam aemulationem;", "brenton": "And he stretched forth the likeness of a hand, and took me by the crown of my head; and the Spirit lifted me up between the earth and sky, and brought me to Jerusalem in a vision of God, to the porch of the gate that looks to the north, where was the pillar of the Purchaser."}}, {"v": 4, "ref": "8:4", "o": "וְ/הִ֨נֵּה שָׁ֔ם כְּב֖וֹד אֱלֹהֵ֣י יִשְׂרָאֵ֑ל כַּ/מַּרְאֶ֕ה אֲשֶׁ֥ר רָאִ֖יתִי בַּ/בִּקְעָֽה", "en": {"kjv": "And, behold, the glory of the God of Israel was there, according to the vision that I saw in the plain.", "web": "Behold, the glory of the God of Israel was there, according to the appearance that I saw in the plain.", "bsb": "And there I saw the glory of the God of Israel, like the vision I had seen in the plain.", "asv": "And, behold, the glory of the God of Israel was there, according to the appearance that I saw in the plain.", "ylt": "and lo, there the honour of the God of Israel, as the appearance that I saw in the valley.", "dra": "And behold the glory of the God of Israel was there, according to the vision which I had seen in the plain.", "bbe": "And I saw the glory of the Lord there, as in the vision which I saw in the valley.", "geneva": "And beholde, the glorie of the God of Israel was there according to the vision, that I saw in the fielde.", "wycliffe": "And lo! the glorie of God of Israel was there, bi siyt which Y siy in the feeld.", "rotherham": "and lo! there, the glory of the God of Israel, like the appearance which I had seen in the valley.", "darby": "And behold, the glory of theGod of Israel was there, according to the appearance that I saw in the valley.", "twenty": "", "jps": "And, behold, the glory of the G-d of Israel was there, according to the vision that I saw in the plain.", "acv": "And, behold, the glory of the God of Israel was there, according to the appearance that I saw in the plain.", "anderson": "", "haweis": "", "noyes": "And behold, the glory of the God of Israel was there, according to the vision which I saw in the plain.", "webster": "And behold, the glory of the God of Israel [was] there, according to the vision that I saw in the plain.", "vulgate": "et ecce ibi gloria Dei Israhel secundum visionem quam videram in campo;", "brenton": "And, behold, the glory of the Lord God of Israel was there, according to the vision which I saw in the plain."}}, {"v": 5, "ref": "8:5", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י בֶּן אָדָ֕ם שָׂא נָ֥א עֵינֶ֖י/ךָ דֶּ֣רֶךְ צָפ֑וֹנָ/ה וָ/אֶשָּׂ֤א עֵינַ/י֙ דֶּ֣רֶךְ צָפ֔וֹנָ/ה וְ/הִנֵּ֤ה מִ/צָּפוֹן֙ לְ/שַׁ֣עַר הַ/מִּזְבֵּ֔חַ סֵ֛מֶל הַ/קִּנְאָ֥ה הַ/זֶּ֖ה בַּ/בִּאָֽה", "en": {"kjv": "Then said he unto me, Son of man, lift up thine eyes now the way toward the north. So I lifted up mine eyes the way toward the north, and behold northward at the gate of the altar this image of jealousy in the entry.", "web": "Then he said to me, Son of man, lift up your eyes now the way toward the north. So I lifted up my eyes the way toward the north, and see, northward of the gate of the altar this image of jealousy in the entry.", "bsb": "“Son of man,” He said to me, “now lift up your eyes to the north.” So I lifted up my eyes to the north, and in the entrance north of the Altar Gate I saw this idol of jealousy.", "asv": "Then said he unto me, Son of man, lift up thine eyes now the way toward the north. So I lifted up mine eyes the way toward the north, and behold, northward of the gate of the altar this image of jealousy in the entry.", "ylt": "And He saith unto me, `Son of man, lift up, I pray thee, thine eyes the way of the north.' And I lift up mine eyes the way of the north, and lo, on the north of the gate of the altar this figure of jealousy, at the entrance.", "dra": "And he said to me: Son of man, lift up thy eyes towards the way of the north, and I lifted up my eyes towards the way of the north: and behold on the north side of the gate of the altar the idol of jealousy in the very entry.", "bbe": "Then he said to me, Son of man, now let your eyes be lifted up in the direction of the north; and on looking in the direction of the north, to the north of the doorway of the altar, I saw this image of envy by the way in.", "geneva": "Then saide he vnto mee, Sonne of man, lift vp thine eyes nowe towarde the North. So I lift vp mine eyes towarde the North, and beholde, Northward, at the gate of the altar, this idole of indignation was in the entrie.", "wycliffe": "And he seide to me, Thou, sone of man, reise thin iyen to the weie of the north; and Y reiside myn iyen to the weie of the north, and lo! fro the north of the yate of the auter the idol of enuye was in that entryng.", "rotherham": "Then said he unto me, Son of man Lift up. I pray thee thine eyes, the way toward the north. So I lifted up mine eyes the way toward the north, and lo! on the north by the gate of the altar, this Statue of Jealousy, in the entrance.", "darby": "And he said unto me, Son of man, lift up now thine eyes toward the north. And I lifted up mine eyes toward the north, and behold, northward of the gate of the altar, this image of jealousy in the entry.", "twenty": "", "jps": "Then said He unto me: 'Son of man, lift up thine eyes now the way toward the north.' So I lifted up mine eyes the way toward the north, and behold northward of the gate of the altar this image of jealousy in the entry.", "acv": "Then he said to me, Son of man, lift up thine eyes now the way toward the north. So I lifted up my eyes the way toward the north, and, behold, northward of the gate of the altar was this image of jealousy in the entry.", "anderson": "", "haweis": "", "noyes": "Then said he to me, Son of man, lift up thine eyes toward the north! And I lifted up my eyes toward the north, and behold, northward from the gate of the altar was this idol of jealousy, at the entrance.", "webster": "Then said he to me, Son of man, lift up thy eyes now the way towards the north. So I lifted up my eyes the way towards the north, and behold northward at the gate of the altar this image of jealousy in the entry.", "vulgate": "et dixit ad me fili hominis leva oculos tuos ad viam aquilonis et levavi oculos meos ad viam aquilonis et ecce ab aquilone portae altaris idolum zeli in ipso introitu;", "brenton": "And he said to me, Son of man, lift up thine eyes toward the north. So I lifted up mine eyes toward the north, and, behold, I looked from the north toward the eastern gate."}}, {"v": 6, "ref": "8:6", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י בֶּן אָדָ֕ם הֲ/רֹאֶ֥ה אַתָּ֖ה מ/הם מָ֣ה הֵ֣ם עֹשִׂ֑ים תּוֹעֵב֨וֹת גְּדֹל֜וֹת אֲשֶׁ֥ר בֵּֽית יִשְׂרָאֵ֣ל עֹשִׂ֣ים פֹּ֗ה לְ/רָֽחֳקָה֙ מֵ/עַ֣ל מִקְדָּשִׁ֔/י וְ/עוֹד֙ תָּשׁ֣וּב תִּרְאֶ֔ה תּוֹעֵב֖וֹת גְּדֹלֽוֹת", "en": {"kjv": "He said furthermore unto me, Son of man, seest thou what they do? even the great abominations that the house of Israel committeth here, that I should go far off from my sanctuary? but turn thee yet again, and thou shalt see greater abominations.", "web": "He said to me, Son of man, do you see what they do? even the great abominations that the house of Israel do commit here, that I should go far off from my sanctuary? But you shall again see yet other great abominations.", "bsb": "“Son of man,” He said to me, “do you see what they are doing—the great abominations that the house of Israel is committing—to drive Me far from My sanctuary? Yet you will see even greater abominations.”", "asv": "And he said unto me, Son of man, seest thou what they do? even the great abominations that the house of Israel do commit here, that I should go far off from my sanctuary? But thou shalt again see yet other great abominations.", "ylt": "And He saith unto me, `Son of man, art thou seeing what they are doing? the great abominations that the house of Israel are doing here, to keep far off from My sanctuary; and again thou dost turn, thou dost see great abominations.'", "dra": "And he said to me: Son of man, dost thou see, thinkest thou, what these are doing, the great abominations that the house of Israel committeth here, that I should depart far off from my sanctuary? and turn thee yet again and thou shalt see greater abominations.", "bbe": "And he said to me, Son of man, do you see what they are doing? even the very disgusting things which the children of Israel are doing here, causing me to go far away from my holy place? but you will see other most disgusting things.", "geneva": "He said furthermore vnto me, Sonne of man, seest thou not what they doe? euen the great abominations that the house of Israel committeth here to cause me to depart from my Sanctuarie? but yet turne thee and thou shalt see greater abominations.", "wycliffe": "And he seide to me, Sone of man, gessist thou whether thou seest what thing these men doon, the grete abhomynaciouns whiche the hous of Israel doith here, that Y go fer awei fro my seyntuarie? and yit thou schalt turne, and schalt se grettere abhomynaciouns.", "rotherham": "Then said he unto me, Son of man Canst thou see what they are doing,—the great abominations which the house of Israel are committing here, that I should go faraway from my sanctuary? Howbeit yet again, shalt thou see great abominations.", "darby": "And he said unto me, Son of man, seest thou what they do? the great abominations that the house of Israel commit here, to cause [me] to go far off from my sanctuary? And yet again thou shalt see great abominations.", "twenty": "", "jps": "And He said unto me: 'Son of man, seest thou what they do? even the great abominations that the house of Israel do commit here, that I should go far off from My sanctuary? but thou shalt again see yet greater abominations.'", "acv": "And he said to me, Son of man, see thou what they do, even the great abominations that the house of Israel commit here, that I should go far off from my sanctuary? But thou shall again see yet other great abominations.", "anderson": "", "haweis": "", "noyes": "And he said to me: Son of man, seest thou what they do? Great are the abominations which the house of Israel commit here, that I should go far off from my sanctuary. But thou shalt yet again see great abominations.", "webster": "He said furthermore to me, Son of man, seest thou what they do? [even] the great abominations that the house of Israel committeth here, that I should withdraw from my sanctuary? but turn thee yet again, [and] thou shalt see greater abominations.", "vulgate": "et dixit ad me fili hominis putasne vides tu quid isti faciant abominationes magnas quas domus Israhel facit hic ut procul recedam a sanctuario meo et adhuc conversus videbis abominationes maiores;", "brenton": "And he said to me, Son of man, hast thou seen what these do? They commit great abominations here so that I should keep away from my sanctuary: and thou shalt see yet greater iniquities."}}, {"v": 7, "ref": "8:7", "o": "וַ/יָּבֵ֥א אֹתִ֖/י אֶל פֶּ֣תַח הֶֽ/חָצֵ֑ר וָ/אֶרְאֶ֕ה וְ/הִנֵּ֥ה חֹר אֶחָ֖ד בַּ/קִּֽיר", "en": {"kjv": "And he brought me to the door of the court; and when I looked, behold a hole in the wall.", "web": "He brought me to the door of the court; and when I looked, behold, a hole in the wall.", "bsb": "Then He brought me to the entrance to the court, and I looked and saw a hole in the wall.", "asv": "And he brought me to the door of the court; and when I looked, behold, a hole in the wall.", "ylt": "And He bringeth me in unto an opening of the court, and I look, and lo, a hole in the wall;", "dra": "And he brought me in to the door of the court: and I saw, and behold a hole in the wall.", "bbe": "And he took me to the door of the open place; and looking, I saw a hole in the wall.", "geneva": "And he caused me to enter at the gate of the court: and when I looked, beholde, an hole was in the wall.", "wycliffe": "And he ledde me with ynne to the dore of the halle; and Y siy, and lo! oon hoole in the wal.", "rotherham": "So he brought me into the opening of the court,—and I looked, and lo! a single hole in the wall.", "darby": "And he brought me to the entry of the court, and I looked, and behold, a hole in the wall.", "twenty": "", "jps": "And He brought me to the door of the court; and when I looked, behold a hole in the wall.", "acv": "And he brought me to the door of the court. And when I looked, behold, a hole in the wall.", "anderson": "", "haweis": "", "noyes": "And he brought me to the door of the court, and I looked, and behold, a hole in the wall.", "webster": "And he brought me to the door of the court; and when I looked, behold a hole in the wall.", "vulgate": "et introduxit me ad ostium atrii et vidi et ecce foramen unum in pariete;", "brenton": "And he brought me to the porch of the court."}}, {"v": 8, "ref": "8:8", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י בֶּן אָדָ֖ם חֲתָר נָ֣א בַ/קִּ֑יר וָ/אֶחְתֹּ֣ר בַּ/קִּ֔יר וְ/הִנֵּ֖ה פֶּ֥תַח אֶחָֽד", "en": {"kjv": "Then said he unto me, Son of man, dig now in the wall: and when I had digged in the wall, behold a door.", "web": "Then he said to me, Son of man, dig now in the wall: and when I had dug in the wall, behold, a door.", "bsb": "“Son of man,” He told me, “dig through the wall.” So I dug through the wall and discovered a doorway.", "asv": "Then said he unto me, Son of man, dig now in the wall: and when I had digged in the wall, behold, a door.", "ylt": "and He saith unto me, `Son of man, dig, I pray thee, through the wall;' and I dig through the wall, and lo, an opening.", "dra": "And he said to me: Son of man, dig in the wall, and when I had digged in the wall, behold a door.", "bbe": "And he said to me, Son of man, make a hole in the wall: and after making a hole in the wall I saw a door.", "geneva": "Then said he vnto me, Sonne of man, digge nowe in the wall. And when I had digged in the wall, beholde, there was a doore.", "wycliffe": "And he seide to me, Sone of man, digge thou the wal; and whanne Y hadde diggid the wal, o dore apperide.", "rotherham": "Then said he unto me Son of man Break I pray thee through the wall. So I broke through the wall, and lo! a single opening.", "darby": "And he said unto me, Son of man, dig now through the wall; and I digged through the wall, and behold, a door.", "twenty": "", "jps": "Then said He unto me: 'Son of man, dig now in the wall'; and when I had digged in the wall, behold a door.", "acv": "Then he said to me, Son of man, dig now in the wall. And when I had dug in the wall, behold, a door.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, break now through the wall. And when I had broken through the wall, behold, a door.", "webster": "Then said he to me, Son of man, dig now in the wall: and when I had digged in the wall, behold a door.", "vulgate": "et dixit ad me fili hominis fode parietem et cum perfodissem parietem apparuit ostium unum;", "brenton": "And he said to me, Son of man, dig: so I dug, and behold a door."}}, {"v": 9, "ref": "8:9", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י בֹּ֤א וּ/רְאֵה֙ אֶת הַ/תּוֹעֵב֣וֹת הָ/רָע֔וֹת אֲשֶׁ֛ר הֵ֥ם עֹשִׂ֖ים פֹּֽה", "en": {"kjv": "And he said unto me, Go in, and behold the wicked abominations that they do here.", "web": "He said to me, Go in, and see the wicked abominations that they do here.", "bsb": "Then He said to me, “Go in and see the wicked abominations they are committing here.”", "asv": "And he said unto me, Go in, and see the wicked abominations that they do here.", "ylt": "And He saith to me, `Go in, and see the evil abominations that they are doing here.'", "dra": "And he said to me: Go in, and see the wicked abominations which they commit here.", "bbe": "And he said to me, Go in and see the evil and disgusting things which they are doing here.", "geneva": "And he said vnto mee, Go in, and beholde the wicked abominations that they doe here.", "wycliffe": "And he seide to me, Entre thou, and se the worste abhomynaciouns, whiche these men doon here.", "rotherham": "Then said he unto me,— Go in, and see the wicked abominations. which they are committing here.", "darby": "And he said unto me, Go in, and behold the wicked abominations that they do here.", "twenty": "", "jps": "And He said unto me: 'Go in, and see the wicked abominations that they do here.'", "acv": "And he said to me, Go in, and see the wicked abominations that they do here.", "anderson": "", "haweis": "", "noyes": "And he said to me, Go in, and behold the wicked abominations which they practise here.", "webster": "And he said to me, Go in, and behold the wicked abominations that they do here.", "vulgate": "et dixit ad me ingredere et vide abominationes pessimas quas isti faciunt hic;", "brenton": "And he said to me, Go in, and behold the iniquities which they practise here."}}, {"v": 10, "ref": "8:10", "o": "וָ/אָבוֹא֮ וָֽ/אֶרְאֶה֒ וְ/הִנֵּ֨ה כָל תַּבְנִ֜ית רֶ֤מֶשׂ וּ/בְהֵמָה֙ שֶׁ֔קֶץ וְ/כָל גִּלּוּלֵ֖י בֵּ֣ית יִשְׂרָאֵ֑ל מְחֻקֶּ֥ה עַל הַ/קִּ֖יר סָבִ֥יב סָבִֽיב", "en": {"kjv": "So I went in and saw; and behold every form of creeping things, and abominable beasts, and all the idols of the house of Israel, pourtrayed upon the wall round about.", "web": "So I went in and saw; and see, every form of creeping things, and abominable animals, and all the idols of the house of Israel, portrayed around on the wall.", "bsb": "So I went in and looked, and engraved all around the wall was every kind of crawling creature and detestable beast, along with all the idols of the house of Israel.", "asv": "So I went in and saw; and behold, every form of creeping things, and abominable beasts, and all the idols of the house of Israel, portrayed upon the wall round about.", "ylt": "And I go in, and look, and lo, every form of creeping thing, and detestable beast--and all the Idols of the house of Israel--graved on the wall, all round about,", "dra": "And I went in and saw, and behold every form of creeping things, and of living creatures, the abominations, and all the idols of the house of Israel, were painted on the wall all round about.", "bbe": "So I went in and saw; and there every sort of living thing which goes flat on the earth, and unclean beasts, and all the images of the children of Israel, were pictured round about on the wall.", "geneva": "So I went in, and sawe, and beholde, there was euery similitude of creeping thinges and abominable beasts and all the idoles of the house of Israel painted vpon the wall round about.", "wycliffe": "And Y entride, and siy; and lo! ech licnesse of `crepynge beestis, and abhomynacioun of beestis, and alle idols of the hous of Israel, weren peyntid in the wal al aboute in cumpas.", "rotherham": "So I went in. and looked, and lo! every similitude of creeping thing, and detestable beast, and all the manufactured gods of the house of Israel,- portrayed upon the wall round about on every side;", "darby": "And I went in and looked, and behold, every form of creeping thing and abominable beast, and all the idols of the house of Israel, portrayed upon the wall round about.", "twenty": "", "jps": "So I went in and saw; and behold every detestable form of creeping things and beasts, and all the idols of the house of Israel, portrayed upon the wall round about.", "acv": "So I went in and saw, and, behold, every form of creeping things, and abominable beasts, and all the idols of the house of Israel, portrayed upon the wall round about.", "anderson": "", "haweis": "", "noyes": "So I went in and saw, and behold, every form of creeping things, and of abominable beasts, and all the idols of the house of Israel, portrayed upon the wall round about.", "webster": "So I went in and saw; and behold every form of creeping animals, and abominable beasts, and all the idols of the house of Israel, portrayed around upon the wall.", "vulgate": "et ingressus vidi et ecce omnis similitudo reptilium et animalium abominatio et universa idola domus Israhel depicta erant in pariete in circuitu per totum;", "brenton": "So I went in and looked; and beheld vain abominations, and all the idols of the house of Israel, portrayed upon them round about."}}, {"v": 11, "ref": "8:11", "o": "וְ/שִׁבְעִ֣ים אִ֣ישׁ מִ/זִּקְנֵ֣י בֵֽית יִ֠שְׂרָאֵל וְ/יַאֲזַנְיָ֨הוּ בֶן שָׁפָ֜ן עֹמֵ֤ד בְּ/תוֹכָ/ם֙ עֹמְדִ֣ים לִ/פְנֵי/הֶ֔ם וְ/אִ֥ישׁ מִקְטַרְתּ֖/וֹ בְּ/יָד֑/וֹ וַ/עֲתַ֥ר עֲנַֽן הַ/קְּטֹ֖רֶת עֹלֶֽה", "en": {"kjv": "And there stood before them seventy men of the ancients of the house of Israel, and in the midst of them stood Jaazaniah the son of Shaphan, with every man his censer in his hand; and a thick cloud of incense went up.", "web": "There stood before them seventy men of the elders of the house of Israel; and in their midst stood Jaazaniah the son of Shaphan, every man with his censer in his hand; and the odor of the cloud of incense went up.", "bsb": "Before them stood seventy elders of the house of Israel, with Jaazaniah son of Shaphan standing among them. Each had a censer in his hand, and a fragrant cloud of incense was rising.", "asv": "And there stood before them seventy men of the elders of the house of Israel; and in the midst of them stood Jaazaniah the son of Shaphan, every man with his censer in his hand; and the odor of the cloud of incense went up.", "ylt": "and seventy men of the elders of the house of Israel--and Jaazaniah son of Shaphan standing in their midst--are standing before them, and each his censer in his hand, and the abundance of the cloud of perfume is going up.", "dra": "And seventy men of the ancients of the house of Israel, and Jezonias the son of Saaphan stood in the midst of them, that stood before the pictures: and every one had a censer in his hand: and a cloud of smoke went up from the incense.", "bbe": "And before them seventy of the responsible men of the children of Israel had taken their places, every man with a vessel for burning perfumes in his hand, and in the middle of them was Jaazaniah, the son of Shaphan; and a cloud of smoke went up from the burning perfume.", "geneva": "And there stoode before them seuentie men of the Ancients of the house of Israel, and in the middes of them stoode Iaazaniah, ye sonne of Shaphan, with euerie man his censour in his hand, and the vapour of the incense went vp like a cloude.", "wycliffe": "And seuenti men of the eldere of the hous of Israel stoden; and Jeconye, the sone of Saphan, stood in the myddis of hem, stondynge bifore the peyntyngis; and ech man hadde a censere in his hond, and the smoke of a cloude of encense stiede.", "rotherham": "and seventy men of the elders of the house of Israel with Jaazaniah son of Shaphan, who stood in their midst were standing before them, even every man with his censer in his hand,—and the fragrance of the cloud of incense ascending.", "darby": "And there stood before them seventy men of the elders of the house of Israel, and in the midst of them stood Jaazaniah the son of Shaphan, with every man his censer in his hand; and a thick cloud of incense went up.", "twenty": "", "jps": "And there stood before them seventy men of the elders of the house of Israel, and in the midst of them stood Jaazaniah the son of Shaphan, every man with his censer in his hand; and a thick cloud of incense went up.", "acv": "And there stood before them seventy men of the elders of the house of Israel. And in the midst of them stood Jaazaniah the son of Shaphan, each man with his censer in his hand, and the odor of the cloud of incense went up.", "anderson": "", "haweis": "", "noyes": "And there stood before them seventy men of the elders of the house of Israel, Jaazaniah, the son of Shaphan, standing in the midst of them, with every man his censer in his hand; and a thick cloud of incense went up.", "webster": "And there stood before them seventy men of the elders of the house of Israel, and in the midst of them stood Jaazaniah the son of Shaphan, with every man his censer in his hand; and a thick cloud of incense went up.", "vulgate": "et septuaginta viri de senioribus domus Israhel et Hiezonias filius Saphan stabat in medio eorum stantium ante picturas et unusquisque habebat turibulum in manu sua et vapor nebulae de ture consurgebat;", "brenton": "And seventy men of the elders of the house of Israel, and Jechonias the son of Saphan stood in their presence in the midst of them, and each one held his censer in his hand; and the smoke of the incense went up."}}, {"v": 12, "ref": "8:12", "o": "וַ/יֹּ֣אמֶר אֵלַ/י֮ הֲ/רָאִ֣יתָ בֶן אָדָם֒ אֲשֶׁ֨ר זִקְנֵ֤י בֵֽית יִשְׂרָאֵל֙ עֹשִׂ֣ים בַּ/חֹ֔שֶׁךְ אִ֖ישׁ בְּ/חַדְרֵ֣י מַשְׂכִּית֑/וֹ כִּ֣י אֹמְרִ֗ים אֵ֤ין יְהוָה֙ רֹאֶ֣ה אֹתָ֔/נוּ עָזַ֥ב יְהוָ֖ה אֶת הָ/אָֽרֶץ", "en": {"kjv": "Then said he unto me, Son of man, hast thou seen what the ancients of the house of Israel do in the dark, every man in the chambers of his imagery? for they say, The Lord seeth us not; the Lord hath forsaken the earth.", "web": "Then he said to me, Son of man, have you seen what the elders of the house of Israel do in the dark, every man in his rooms of imagery? for they say, Yahweh doesn’t see us; Yahweh has forsaken the land.", "bsb": "“Son of man,” He said to me, “do you see what the elders of the house of Israel are doing in the darkness, each at the shrine of his own idol? For they are saying, ‘The LORD does not see us; the LORD has forsaken the land.’”", "asv": "Then said he unto me, Son of man, hast thou seen what the elders of the house of Israel do in the dark, every man in his chambers of imagery? for they say, Jehovah seeth us not; Jehovah hath forsaken the land.", "ylt": "And He saith unto me, `Hast thou seen, son of man, that which elders of the house of Israel are doing in darkness, each in the inner chambers of his imagery, for they are saying, Jehovah is not seeing us, Jehovah hath forsaken the land?'", "dra": "And he said to me: Surely thou seest, O son of man, what the ancients of the house of Israel do in the dark, every one in private in his chamber: for they say: The Lord seeth us not, the Lord hath forsaken the earth.", "bbe": "And he said to me, Son of man, have you seen what the responsible men of the children of Israel do in the dark, every man in his room of pictured images? for they say, The Lord does not see us; the Lord has gone away from the land.", "geneva": "Then saide hee vnto mee, Sonne of man, hast thou seene what the Ancients of the house of Israel do in the darke, euery one in the chamber of his imagerie? for they say, The Lord seeth vs not, the Lord hath forsaken the earth.", "wycliffe": "And he seide to me, Certis, sone of man, thou seest what thingis the eldere men of the hous of Israel doen in derknessis, ech man in the hid place of his bed; for thei seiyn, The Lord seeth not vs, the Lord hath forsake the lond.", "rotherham": "Then said he unto me, Hast thou seen Son of man what the elders of the house of Israel, are doing in the dark, every man in his image-chambers? for they are saying— Yahweh doth not see us! Yahweh hath forsaken the land!", "darby": "And he said unto me, Hast thou seen, son of man, what the elders of the house of Israel do in the dark, every one in his chambers of imagery? for they say, Jehovah seeth us not; Jehovah hath forsaken the land.", "twenty": "", "jps": "Then said He unto me: 'Son of man, hast thou seen what the elders of the house of Israel do in the dark, every man in his chambers of imagery? for they say: HaShem seeth us not, HaShem hath forsaken the land.'", "acv": "Then he said to me, Son of man, have thou seen what the elders of the house of Israel do in the dark, each man in his chambers of imagery? For they say, Jehovah does not see us. Jehovah has forsaken the land.", "anderson": "", "haweis": "", "noyes": "Then said he to me: Son of man, seest thou what the elders of the house of Israel do in the dark, each one in his image-chamber? For they say, \"Jehovah seeth us not; Jehovah hath forsaken the land.\"", "webster": "Then said he to me, Son of man, hast thou seen what the elders of the house of Israel do in the dark, every man in the chambers of his imagery? for they say, The LORD seeth us not; the LORD hath forsaken the earth.", "vulgate": "et dixit ad me certe vides fili hominis quae seniores domus Israhel faciunt in tenebris unusquisque in abscondito cubiculi sui dicunt enim non videt Dominus nos dereliquit Dominus terram;", "brenton": "And he said to me, Thou hast seen, son of man, what the elders of the house of Israel do, each one of them in their secret chamber: because they have said, The Lord see not; The Lord has forsaken the earth."}}, {"v": 13, "ref": "8:13", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י ע֣וֹד תָּשׁ֥וּב תִּרְאֶ֛ה תּוֹעֵב֥וֹת גְּדֹל֖וֹת אֲשֶׁר הֵ֥מָּה עֹשִֽׂים", "en": {"kjv": "He said also unto me, Turn thee yet again, and thou shalt see greater abominations that they do.", "web": "He said also to me, You shall again see yet other great abominations which they do.", "bsb": "Again, He told me, “You will see them committing even greater abominations.”", "asv": "He said also unto me, Thou shalt again see yet other great abominations which they do.", "ylt": "And He saith unto me, `Again thou dost turn, thou dost see great abominations that they are doing.'", "dra": "And he said to me: If thou turn thee again, thou shalt see greater abominations which these commit.", "bbe": "Then he said to me, You will see even more disgusting things which they do.", "geneva": "Againe he saide also vnto me, Turne thee againe, and thou shalt see greater abominations that they doe.", "wycliffe": "And the Lord seide to me, Yit thou schalt turne, and schalt se gretter abhomynaciouns, whiche these men doon.", "rotherham": "Then said he unto me,— Yet again, shalt thou see great abominations, which they are committing.", "darby": "And he said unto me, Yet again thou shalt see great abominations which they do.", "twenty": "", "jps": "He said also unto me: 'Thou shalt again see yet greater abominations which they do.'", "acv": "He also said to me, Thou shall again see yet other great abominations which they do.", "anderson": "", "haweis": "", "noyes": "And he said to me, Thou shalt yet again see the great abominations which they practise.", "webster": "He said also to me, Turn thee yet again, [and] thou shalt see greater abominations that they do.", "vulgate": "et dixit ad me adhuc conversus videbis abominationes maiores quas isti faciunt;", "brenton": "And he said to me, Thou shalt see yet greater iniquities which these do."}}, {"v": 14, "ref": "8:14", "o": "וַ/יָּבֵ֣א אֹתִ֗/י אֶל פֶּ֨תַח֙ שַׁ֣עַר בֵּית יְהוָ֔ה אֲשֶׁ֖ר אֶל הַ/צָּפ֑וֹנָ/ה וְ/הִנֵּה שָׁם֙ הַ/נָּשִׁ֣ים יֹֽשְׁב֔וֹת מְבַכּ֖וֹת אֶת הַ/תַּמּֽוּז", "en": {"kjv": "Then he brought me to the door of the gate of the Lord’s house which was toward the north; and, behold, there sat women weeping for Tammuz.", "web": "Then he brought me to the door of the gate of Yahweh’s house which was toward the north; and see, there sat the women weeping for Tammuz.", "bsb": "Then He brought me to the entrance of the north gate of the house of the LORD, and I saw women sitting there, weeping for Tammuz.", "asv": "Then he brought me to the door of the gate of Jehovah’s house which was toward the north; and behold, there sat the women weeping for Tammuz.", "ylt": "And He bringeth me in unto the opening of the gate of the house of Jehovah that is at the north, and lo, there the women are sitting weeping for Tammuz.", "dra": "And he brought me in by the door of the gate of the Lord's house, which looked to the north: and behold women sat there mourning for Adonis.", "bbe": "Then he took me to the door of the way into the Lord's house looking to the north; and there women were seated weeping for Tammuz.", "geneva": "And he caused me to enter into the entrie of the gate of the Lords house, which was toward the North: and beholde there sate women mourning for Tammuz.", "wycliffe": "And he ledde me with ynne, bi the dore of the yate of the hous of the Lord, which dore bihelde to the north; and lo! wymmen saten there, biweilynge Adonydes.", "rotherham": "So he brought me into the opening of the gate of the house of Yahweh, which was toward the north,—and Lo! there, women sitting, weeping for Tammuz.", "darby": "And he brought me to the entry of the gate of Jehovah's house that was toward the north; and behold, there sat women weeping for Tammuz.", "twenty": "", "jps": "Then He brought me to the door of the gate of HaShem'S house which was toward the north; and, behold, there sat the women weeping for Tammuz.", "acv": "Then he brought me to the door of the gate of Jehovah's house which was toward the north. And, behold, there sat the women weeping for Tammuz.", "anderson": "", "haweis": "", "noyes": "Then he brought me to the entrance of the gate of the house of Jehovah, which was toward the north, and behold, there sat women, weeping for Thammuz.", "webster": "Then he brought me to the door of the gate of the LORD'S house which [was] towards the north; and behold, there sat women weeping for Tammuz.", "vulgate": "et introduxit me per ostium portae domus Domini quod respiciebat ad aquilonem et ecce ibi mulieres sedebant plangentes Adonidem;", "brenton": "And he brought me in to the porch of the house of the Lord that looks to the north; and, behold there were women sitting there lamenting for Thammuz."}}, {"v": 15, "ref": "8:15", "o": "וַ/יֹּ֥אמֶר אֵלַ֖/י הֲ/רָאִ֣יתָ בֶן אָדָ֑ם ע֣וֹד תָּשׁ֥וּב תִּרְאֶ֛ה תּוֹעֵב֥וֹת גְּדֹל֖וֹת מֵ/אֵֽלֶּה", "en": {"kjv": "Then said he unto me, Hast thou seen this, O son of man? turn thee yet again, and thou shalt see greater abominations than these.", "web": "Then he said to me, Have you seen this, son of man? You shall again see yet greater abominations than these.", "bsb": "“Son of man,” He said to me, “do you see this? Yet you will see even greater abominations than these.”", "asv": "Then said he unto me, Hast thou seen this, O son of man? thou shalt again see yet greater abominations than these.", "ylt": "And He saith unto me, `Hast thou seen, son of man? again thou dost turn, thou dost see greater abominations than these.'", "dra": "And he said to me: Surely thou hast seen, O son of man: but turn thee again, thou shalt see greater abominations than these.", "bbe": "Then he said to me, Have you seen this, O son of man? you will see even more disgusting things than these.", "geneva": "Then saide hee vnto me, Hast thou seene this, O sonne of man? Turne thee againe, and thou shalt see greater abominations then these.", "wycliffe": "And the Lord seide to me, Certis, sone of man, thou hast seyn; yit thou schalt turne, and schalt se gretere abhomynaciouns than these.", "rotherham": "Then said he unto me Hast thou seen O son of man? Yet again, shalt thou see greater abominations than these.", "darby": "And he said unto me, Seest thou, son of man? Thou shalt yet again see greater abominations than these.", "twenty": "", "jps": "Then said He unto me: 'Hast thou seen this, O son of man? thou shalt again see yet greater abominations than these.'", "acv": "Then he said to me, Have thou seen this, O son of man? Thou shall again see yet greater abominations than these.", "anderson": "", "haweis": "", "noyes": "And he said to me, Seest thou this, O son of man? Thou shalt yet again see greater abominations than these.", "webster": "Then said he to me, Hast thou seen [this], O son of man? turn thee yet again, [and] thou shalt see greater abominations than these.", "vulgate": "et dixit ad me certe vidisti fili hominis adhuc conversus videbis abominationes maiores his;", "brenton": "And he said to me, Son of man, thou hast seen; but thou shalt yet see evil practices greater then these."}}, {"v": 16, "ref": "8:16", "o": "וַ/יָּבֵ֣א אֹתִ֗/י אֶל חֲצַ֣ר בֵּית יְהוָה֮ הַ/פְּנִימִית֒ וְ/הִנֵּה פֶ֜תַח הֵיכַ֣ל יְהוָ֗ה בֵּ֤ין הָֽ/אוּלָם֙ וּ/בֵ֣ין הַ/מִּזְבֵּ֔חַ כְּ/עֶשְׂרִ֥ים וַ/חֲמִשָּׁ֖ה אִ֑ישׁ אֲחֹ֨רֵי/הֶ֜ם אֶל הֵיכַ֤ל יְהוָה֙ וּ/פְנֵי/הֶ֣ם קֵ֔דְמָ/ה וְ/הֵ֛מָּה מִשְׁתַּחֲוִיתֶ֥ם קֵ֖דְמָ/ה לַ/שָּֽׁמֶשׁ", "en": {"kjv": "And he brought me into the inner court of the Lord’s house, and, behold, at the door of the temple of the Lord, between the porch and the altar, were about five and twenty men, with their backs toward the temple of the Lord, and their faces toward the east; and they worshipped the sun toward the east.", "web": "He brought me into the inner court of Yahweh’s house; and see, at the door of Yahweh’s temple, between the porch and the altar, were about twenty-five men, with their backs toward Yahweh’s temple, and their faces toward the east; and they were worshiping the sun toward the east.", "bsb": "So He brought me to the inner court of the house of the LORD, and there at the entrance to the temple of the LORD, between the portico and the altar, were about twenty-five men with their backs to the temple of the LORD and their faces toward the east; and they were bowing to the east in worship of the sun.", "asv": "And he brought me into the inner court of Jehovah’s house; and behold, at the door of the temple of Jehovah, between the porch and the altar, were about five and twenty men, with their backs toward the temple of Jehovah, and their faces toward the east; and they were worshipping the sun toward the east.", "ylt": "And He bringeth me in unto the inner court of the house of Jehovah, and lo, at the opening of the temple of Jehovah, between the porch and the altar, about twenty-five men, their backs toward the temple of Jehovah, and their faces eastward, and they are bowing themselves eastward to the sun.", "dra": "And he brought me into the inner court of the house of the Lord: and behold at the door of the temple of the Lord, between the porch and the altar, were about five and twenty men having their backs towards the temple of the Lord, in their faces to the east: and they adored towards the rising of the sun.", "bbe": "And he took me into the inner square of the Lord's house, and at the door of the Temple of the Lord, between the covered way and the altar, there were about twenty-five men with their backs turned to the Temple of the Lord and their faces turned to the east; and they were worshipping the sun, turning to the east.", "geneva": "And he caused me to enter into the inner court of the Lordes house, and beholde, at the doore of the Temple of the Lord, betweene the porche and the altar were about fiue and twentie men with their backs toward the Temple of the Lord, and their faces towarde the East, and they worshipped the sunne, towarde the East.", "wycliffe": "And he ledde me with ynne, in to the ynnere halle of the hous of the Lord; and lo! in the dore of the temple of the Lord, bitwixe the porche and the auter, weren as fyue and twenti men hauynge the backis ayens the temple of the Lord, and her faces to the eest; and thei worschipiden at the risyng of the sunne.", "rotherham": "So he brought me into the inner court of the house of Yahweh, and lo! at the opening of the temple of Yahweh, between the porch and the altar, about twenty-five men,—their backs towards the temple of Yahweh and their faces eastward, and they were bowing down eastward unto the Sun.", "darby": "And he brought me into the inner court of Jehovah's house, and behold, at the entry of the temple of Jehovah, between the porch and the altar, were about five and twenty men, with their backs toward the temple of Jehovah and their faces toward the east; and they worshipped the sun toward the east.", "twenty": "", "jps": "And He brought me into the inner court of HaShem'S house, and, behold, at the door of the temple of HaShem, between the porch and the altar, were about five and twenty men, with their backs toward the temple of HaShem, and their faces toward the east; and they worshipped the sun toward the east.", "acv": "And he brought me into the inner court of Jehovah's house. And, behold, at the door of the temple of Jehovah, between the porch and the altar, were about twenty-five men with their backs toward the temple of Jehovah, and their faces toward the east, and they were worshiping the sun toward the east.", "anderson": "", "haweis": "", "noyes": "And he brought me into the inner court of the house of Jehovah, and behold, at the entrance of the temple of Jehovah, between the porch and the altar, were about five and twenty men, with their backs toward the temple of Jehovah, and their faces toward the east; and they bowed themselves eastward toward the sun.", "webster": "And he brought me into the inner court of the LORD'S house, and behold, at the door of the temple of the LORD, between the porch and the altar, [were] about five and twenty men, with their backs towards the temple of the LORD, and their faces towards the east; and they worshiped the sun towards the east.", "vulgate": "et introduxit me in atrium domus Domini interius et ecce in ostio templi Domini inter vestibulum et altare quasi viginti quinque viri dorsa habentes contra templum Domini et facies ad orientem et adorabant ad ortum solis;", "brenton": "And he brought me into the inner court of the house of the Lord, and at the entrance of the temple of the Lord, between the porch and the altar, were about twenty men, with their back parts toward the temple of the Lord, and their faces turned the opposite way; and these were worshipping the sun."}}, {"v": 17, "ref": "8:17", "o": "וַ/יֹּ֣אמֶר אֵלַ/י֮ הֲ/רָאִ֣יתָ בֶן אָדָם֒ הֲ/נָקֵל֙ לְ/בֵ֣ית יְהוּדָ֔ה מֵ/עֲשׂ֕וֹת אֶת הַ/תּוֹעֵב֖וֹת אֲשֶׁ֣ר עָֽשׂוּ פֹ֑ה כִּֽי מָלְא֨וּ אֶת הָ/אָ֜רֶץ חָמָ֗ס וַ/יָּשֻׁ֨בוּ֙ לְ/הַכְעִיסֵ֔/נִי וְ/הִנָּ֛/ם שֹׁלְחִ֥ים אֶת הַ/זְּמוֹרָ֖ה אֶל אַפָּֽ/ם", "en": {"kjv": "Then he said unto me, Hast thou seen this, O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? for they have filled the land with violence, and have returned to provoke me to anger: and, lo, they put the branch to their nose.", "web": "Then he said to me, Have you seen this, son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? for they have filled the land with violence, and have turned again to provoke me to anger: and behold, they put the branch to their nose.", "bsb": "“Son of man,” He said to me, “do you see this? Is it not enough for the house of Judah to commit the abominations they are practicing here, that they must also fill the land with violence and continually provoke Me to anger? Look, they are even putting the branch to their nose!", "asv": "Then he said unto me, Hast thou seen this, O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? for they have filled the land with violence, and have turned again to provoke me to anger: and, lo, they put the branch to their nose.", "ylt": "And He saith unto me, `Hast thou seen, son of man? hath it been a light thing to the house of Judah to do the abomination that they have done here, that they have filled the land with violence, and turn back to provoke Me to anger? and lo, they are putting forth the branch unto their nose!", "dra": "And he said to me: Surely thou hast seen, O son of man: is this a light thing to the house of Juda, that they should commit these abominations which they have committed here: because they have filled the land with iniquity, and have turned to provoke me to anger? and behold they put a branch to their nose.", "bbe": "Then he said to me, Have you seen this, O son of man? is it a small thing to the children of Judah that they do the disgusting things which they are doing here? for they have made the land full of violent behaviour, making me angry again and again: and see, they put the branch to my nose.", "geneva": "The he said vnto me, Hast thou seene this, O sonne of man? Is it a small thing to the house of Iudah to commit these abominations which they do here? for they haue filled the land with crueltie, and haue returned to prouoke mee: and loe, they haue cast out stinke before their noses.", "wycliffe": "And the Lord seide to me, Certis, sone of man, thou hast seyn; whether this is a liyt thing to the hous of Juda, that thei schulden do these abhomynaciouns, whiche thei diden here? For thei filliden the lond with wickidnesse, and turneden to terre me to wraththe; and lo! thei applien a braunche to her nose thirlis.", "rotherham": "Then said he unto me Hast thou seen O son of man? Is it too small a thing for the house of Judah, to be committing the abominations which they have committed here,—that they have filled the land with violence and have again provoked me to anger and there they are! putting the branch to my nose.", "darby": "And he said unto me, Seest thou, son of man? Is it a light thing to the house of Judah to commit the abominations which they commit here, that they yet fill the land with violence, and keep provoking me afresh to anger? And behold, they put the branch to their nose.", "twenty": "", "jps": "Then He said unto me: 'Hast thou seen this, O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here in that they fill the land with violence, and provoke Me still more, and, lo, they put the branch to their nose?", "acv": "Then he said to me, Have thou seen this, O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? For they have filled the land with violence, and have turned again to provoke me to anger. And, lo, they put the branch to their nose.", "anderson": "", "haweis": "", "noyes": "And he said to me: Seest thou, O son of man? Is it a light thing to the house of Judah, that they commit the abominations which they commit here, that they fill the land with violence, and continually provoke me to anger? And behold, they put the blanch to their nostrils.", "webster": "Then he said to me, Hast thou seen [this], O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? for they have filled the land with violence, and have returned to provoke me to anger: and lo, they put the branch to their nose.", "vulgate": "et dixit ad me certe vidisti fili hominis numquid leve est hoc domui Iuda ut facerent abominationes istas quas fecerunt hic quia replentes terram iniquitate conversi sunt ad inritandum me et ecce adplicant ramum ad nares suas;", "brenton": "And he said to me, Son of man, thou hast seen this. Is it a little thing to the house of Juda to practise the iniquities which they have practised here? for they have filled the land with iniquity: and, behold, these are as scorners."}}, {"v": 18, "ref": "8:18", "o": "וְ/גַם אֲנִי֙ אֶעֱשֶׂ֣ה בְ/חֵמָ֔ה לֹֽא תָח֥וֹס עֵינִ֖/י וְ/לֹ֣א אֶחְמֹ֑ל וְ/קָרְא֤וּ בְ/אָזְנַ/י֙ ק֣וֹל גָּד֔וֹל וְ/לֹ֥א אֶשְׁמַ֖ע אוֹתָֽ/ם", "en": {"kjv": "Therefore will I also deal in fury: mine eye shall not spare, neither will I have pity: and though they cry in mine ears with a loud voice, yet will I not hear them.", "web": "Therefore will I also deal in wrath; my eye shall not spare, neither will I have pity; and though they cry in my ears with a loud voice, yet will I not hear them.", "bsb": "Therefore I will respond with wrath. I will not look on them with pity, nor will I spare them. Although they shout loudly in My ears, I will not listen to them.”", "asv": "Therefore will I also deal in wrath; mine eye shall not spare, neither will I have pity; and though they cry in mine ears with a loud voice, yet will I not hear them.", "ylt": "And I also deal in fury, Mine eye doth not pity, nor do I spare, and they have cried in Mine ears--a loud voice--and I do not hear them.'", "dra": "Therefore I also will deal with them in my wrath: my eye shall not spare them, neither will I shew mercy: and when they shall cry to my ears with a loud voice, I will not hear them.", "bbe": "For this reason I will let loose my wrath: my eye will not have mercy, and I will have no pity.", "geneva": "Therefore will I also execute my wrath: mine eye shall not spare them, neither will I haue pitie, and though they crie in mine eares with a loude voyce, yet will I not heare them.", "wycliffe": "Therfor and Y schal do in strong veniaunce; myn iye schal not spare, nether Y schal do merci; and whanne thei schulen crie to myn eris with greet vois, Y schal not here hem.", "rotherham": "Therefore even I, will act with indignation, Mine eye shall not shield. Neither will I pity,— Though they have cried in mine ears with a loud voice, yet will I not hear them.", "darby": "And I also will deal in fury: mine eye shall not spare, neither will I have pity; and though they cry in mine ears with a loud voice, I will not hear them.", "twenty": "", "jps": "Therefore will I also deal in fury; Mine eye shall not spare, neither will I have pity; and though they cry in Mine ears with a loud voice, yet will I not hear them.'", "acv": "Therefore I will also deal in wrath. My eye shall not spare, nor will I have pity. And though they cry in my ears with a loud voice, yet I will not hear them.", "anderson": "", "haweis": "", "noyes": "Therefore will I also deal with them in fury; mine eye shall not spare, neither will I have pity; and though they cry in mine ears with a loud voice, yet will I not hear them.", "webster": "Therefore will I also deal in fury: my eye shall not spare, neither will I have pity: and though they cry in my ears with a loud voice, [yet] I will not hear them.", "vulgate": "ergo et ego faciam in furore non parcet oculus meus nec miserebor et cum clamaverint ad aures meas voce magna non exaudiam eos;", "brenton": "Therefore will I deal with them in wrath: mine eye shall not spare, nor will I have any mercy."}}]}, {"c": 9, "verses": [{"v": 1, "ref": "9:1", "o": "וַ/יִּקְרָ֣א בְ/אָזְנַ֗/י ק֤וֹל גָּדוֹל֙ לֵ/אמֹ֔ר קָרְב֖וּ פְּקֻדּ֣וֹת הָ/עִ֑יר וְ/אִ֛ישׁ כְּלִ֥י מַשְׁחֵת֖/וֹ בְּ/יָדֽ/וֹ", "en": {"kjv": "He cried also in mine ears with a loud voice, saying, Cause them that have charge over the city to draw near, even every man with his destroying weapon in his hand.", "web": "Then he cried in my ears with a loud voice, saying, Cause those who are in charge of the city to draw near, every man with his destroying weapon in his hand.", "bsb": "Then I heard Him call out in a loud voice, saying, “Draw near, O executioners of the city, each with a weapon of destruction in hand.”", "asv": "Then he cried in mine ears with a loud voice, saying, Cause ye them that have charge over the city to draw near, every man with his destroying weapon in his hand.", "ylt": "And He crieth in mine ears--a loud voice--saying, `Drawn near have inspectors of the city, and each his destroying weapon in his hand.'", "dra": "And he cried in my ears with a loud voice, saying: The visitations of the city are at hand, and every one hath a destroying weapon in his hand.", "bbe": "Then crying out in my hearing in a loud voice, he said, Let the overseers of the town come near, every man armed.", "geneva": "He cryed also with a loude voyce in mine eares, saying, The visitations of the citie draw neere, and euery man hath a weapon in his hande to destroy it.", "wycliffe": "And he criede in myn eeris with greet vois, and seide, The visityngis of the citee han neiyed, and ech man hath in his hond an instrument of sleyng.", "rotherham": "Then cried he in mine ears with a loud voice, saying, Draw near ye that have charge of the city,-even every man with his weapon of destruction in his hand.", "darby": "And he cried in mine ears with a loud voice, saying, Draw near, ye that have charge of the city, and every man [with] his destroying weapon in his hand.", "twenty": "", "jps": "Then he called in mine ears with a loud voice, saying: 'Cause ye them that have charge over the city to draw near, every man with his destroying weapon in his hand.'", "acv": "Then he cried in my ears with a loud voice, saying, Cause ye those who have charge over the city to draw near, each man with his destroying weapon in his hand.", "anderson": "", "haweis": "", "noyes": "He cried also, in my hearing, with a loud voice, saying: Bring ye near the punishments of the city, every one his weapon of destruction in his hand.", "webster": "He cried also in my ears with a loud voice, saying, Cause them that have charge over the city to draw near, even every man [with] his destroying weapon in his hand.", "vulgate": "et clamavit in auribus meis voce magna dicens adpropinquaverunt visitationes urbis et unusquisque vas interfectionis habet in manu sua;", "brenton": "And he cried in mine ears with a loud voice, saying, The judgment of the city has drawn nigh; and each had the weapons of destruction in his hand."}}, {"v": 2, "ref": "9:2", "o": "וְ/הִנֵּ֣ה שִׁשָּׁ֣ה אֲנָשִׁ֡ים בָּאִ֣ים מִ/דֶּרֶךְ שַׁ֨עַר הָ/עֶלְי֜וֹן אֲשֶׁ֣ר מָפְנֶ֣ה צָפ֗וֹנָ/ה וְ/אִ֨ישׁ כְּלִ֤י מַפָּצ/וֹ֙ בְּ/יָד֔/וֹ וְ/אִישׁ אֶחָ֤ד בְּ/תוֹכָ/ם֙ לָבֻ֣שׁ בַּדִּ֔ים וְ/קֶ֥סֶת הַ/סֹּפֵ֖ר בְּ/מָתְנָ֑י/ו וַ/יָּבֹ֨אוּ֙ וַ/יַּ֣עַמְד֔וּ אֵ֖צֶל מִזְבַּ֥ח הַ/נְּחֹֽשֶׁת", "en": {"kjv": "And, behold, six men came from the way of the higher gate, which lieth toward the north, and every man a slaughter weapon in his hand; and one man among them was clothed with linen, with a writer’s inkhorn by his side: and they went in, and stood beside the brasen altar.", "web": "Behold, six men came from the way of the upper gate, which lies toward the north, every man with his slaughter weapon in his hand; and one man in their midst clothed in linen, with a writer’s inkhorn by his side. They went in, and stood beside the bronze altar.", "bsb": "And I saw six men coming from the direction of the Upper Gate, which faces north, each with a weapon of slaughter in his hand. With them was another man clothed in linen who had a writing kit at his side. And they came in and stood beside the bronze altar.", "asv": "And behold, six men came from the way of the upper gate, which lieth toward the north, every man with his slaughter weapon in his hand; and one man in the midst of them clothed in linen, with a writer’s inkhorn by his side. And they went in, and stood beside the brazen altar.", "ylt": "And lo, six men are coming from the way of the upper gate, that is facing the north, and each his slaughter-weapon in his hand, and one man in their midst is clothed with linen, and a scribe's inkhorn at his loins, and they come in, and stand near the brazen altar.", "dra": "And behold six men came from the way of the upper gate, which looketh to the north: and each one had his weapon of destruction in his hand: and there was one man in the midst of them clothed with linen, with a writer's inkhorn at his reins: and they went in, and stood by the brazen altar.", "bbe": "And six men came from the way of the higher doorway looking to the north, every man with his axe in his hand: and one man among them was clothed in linen, with a writer's inkpot at his side. And they went in and took their places by the brass altar.", "geneva": "And beholde, sixe men came by the way of the hie gate, which lieth towarde the North, and euery man a weapon in his hande to destroy it: and one man among them was clothed with linen, with a writers ynkhorne by his side, and they went in and stoode beside the brasen altar.", "wycliffe": "And lo! sixe men camen fro the weie of the hiyere yate, that biholdith to the north, and the instrument of deth of ech man was in his hond; also o man in the myddis of hem was clothid with lynnun clothis, and a pennere of a writere at hise reynes; and thei entriden, and stoden bisidis the brasun auter.", "rotherham": "And lo! six men coming in out of the way of the upper gate which looketh toward the north even every man with his destructive weapon in his hand, and one man in their midst clothed with linen, having a scribe’s ink holder by his side,—so they came in and stood beside the altar of bronze.", "darby": "And behold, six men came from the way of the upper gate, which is turned toward the north, and every man [with] his slaughter weapon in his hand; and in the midst of them, one man clothed with linen, with a writer's ink-horn by his side; and they went in, and stood beside the brazen altar.", "twenty": "", "jps": "And, behold, six men came from the way of the upper gate, which lieth toward the north, every man with his weapon of destruction in his hand; and one man in the midst of them clothed in linen, with a writer's inkhorn on his side. And they went in, and stood beside the brazen altar.", "acv": "And, behold, six men came from the way of the upper gate, which lies toward the north, each man with his slaughter weapon in his hand, and one man in the midst of them clothed in linen, with a writer's case by his side. And they went in, and stood beside the brazen altar.", "anderson": "", "haweis": "", "noyes": "And lo, six men came from the way of the higher gate, which looketh toward the north, every one with his slaughter-weapon in his hand; and one man among them was clothed with linen, with a writer’s ink-horn by his side; and they went in, and stood beside the brazen altar.", "webster": "And behold, six men came from the way of the higher gate, which lieth towards the north, and every man a slaughter-weapon in his hand; and one man among them [was] clothed with linen, with a writer's inkhorn by his side: and they went in and stood beside the brazen altar.", "vulgate": "et ecce sex viri veniebant de via portae superioris quae respicit ad aquilonem et uniuscuiusque vas interitus in manu eius vir quoque unus in medio eorum vestitus lineis et atramentarium scriptoris ad renes eius et ingressi sunt et steterunt iuxta altare aereum;", "brenton": "And, behold, six men came from the way of the high gate that looks toward the north, and each one's axe was in his hand; and there was one man in the midst of them clothed with a long robe down to the feet, and a sapphire girdle was on his loins: and they came in and stood near the brazen altar."}}, {"v": 3, "ref": "9:3", "o": "וּ/כְב֣וֹד אֱלֹהֵ֣י יִשְׂרָאֵ֗ל נַעֲלָה֙ מֵ/עַ֤ל הַ/כְּרוּב֙ אֲשֶׁ֣ר הָיָ֣ה עָלָ֔י/ו אֶ֖ל מִפְתַּ֣ן הַ/בָּ֑יִת וַ/יִּקְרָ֗א אֶל הָ/אִישׁ֙ הַ/לָּבֻ֣שׁ הַ/בַּדִּ֔ים אֲשֶׁ֛ר קֶ֥סֶת הַ/סֹּפֵ֖ר בְּ/מָתְנָֽי/ו", "en": {"kjv": "And the glory of the God of Israel was gone up from the cherub, whereupon he was, to the threshold of the house. And he called to the man clothed with linen, which had the writer’s inkhorn by his side;", "web": "The glory of the God of Israel was gone up from the cherub, whereupon it was, to the threshold of the house: and he called to the man clothed in linen, who had the writer’s inkhorn by his side.", "bsb": "Then the glory of the God of Israel rose from above the cherubim, where it had been, and moved to the threshold of the temple. And He called to the man clothed in linen who had the writing kit at his side.", "asv": "And the glory of the God of Israel was gone up from the cherub, whereupon it was, to the threshold of the house: and he called to the man clothed in linen, who had the writer’s inkhorn by his side.", "ylt": "And the honour of the God of Israel hath gone up from off the cherub, on which it hath been, unto the threshold of the house.", "dra": "And the glory of the Lord of Israel went up from the cherub, upon which he was, to the threshold of the house: and he called to the man that was clothed with linen, and had a writer's inkhorn at his loins.", "bbe": "And the glory of the God of Israel had gone up from the winged ones on which it was resting, to the doorstep of the house. And crying out to the man clothed in linen who had the writer's inkpot at his side,", "geneva": "And the glorie of the God of Israel was gone vp from ye Cherub, whereupon he was and stoode on the doore of the house, and he called to the man clothed with linnen, which had the writers ynkhorne by his side.", "wycliffe": "And the glorie of the Lord of Israel was takun vp fro cherub, which glorie was on it, to the threisfold of the hous; and the Lord clepide the man that was clothid with lynun clothis, and hadde a pennere of a writere in hise leendis.", "rotherham": "And the glory of the God of Israel lifted itself up from off the cherub whereon it had been, unto the threshold of the house,—and he called unto the man clothed with linen, who had the scribe’s ink holder by his side.", "darby": "And the glory of theGod of Israel was gone up from the cherub, whereupon it was, to the threshold of the house; and he called to the man clothed with linen, who had the writer's ink-horn by his side;", "twenty": "", "jps": "And the glory of the G-d of Israel was gone up from the cherub, whereupon it was, to the threshold of the house; and He called to the man clothed in linen, who had the writer's inkhorn on his side.", "acv": "And the glory of the God of Israel went up from the cherub, upon which it was, to the threshold of the house, and he called to the man clothed in linen who had the writer's case by his side.", "anderson": "", "haweis": "", "noyes": "And the glory of the God of Israel went up from the cherub upon which it was to the threshold of the house; and he called to the man clothed with linen, who had the writer’s ink-horn by his side;", "webster": "And the glory of the God of Israel had gone up from the cherub on which he was, to the threshhold of the house. And he called to the man clothed with linen, who [had] the writer's inkhorn by his side;", "vulgate": "et gloria Domini Israhel adsumpta est de cherub quae erat super eum ad limen domus et vocavit virum qui indutus erat lineis et atramentarium scriptoris habebat in lumbis suis;", "brenton": "And the glory of the God of Israel, that was upon them, went up from the cherubs to the porch of the house. And he called the man that was clothed with the long robe, who had the girdle on his loins;"}}, {"v": 4, "ref": "9:4", "o": "וַ/יֹּ֤אמֶר יְהוָה֙ אל/ו אֵלָ֔י/ו עֲבֹר֙ בְּ/ת֣וֹךְ הָ/עִ֔יר בְּ/ת֖וֹךְ יְרֽוּשָׁלִָ֑ם וְ/הִתְוִ֨יתָ תָּ֜ו עַל מִצְח֣וֹת הָ/אֲנָשִׁ֗ים הַ/נֶּֽאֱנָחִים֙ וְ/הַ/נֶּ֣אֱנָקִ֔ים עַ֚ל כָּל הַ/תּ֣וֹעֵב֔וֹת הַֽ/נַּעֲשׂ֖וֹת בְּ/תוֹכָֽ/הּ", "en": {"kjv": "And the Lord said unto him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that be done in the midst thereof.", "web": "Yahweh said to him, Go through the midst of the city, through the midst of Jerusalem, and set a mark on the foreheads of the men that sigh and that cry over all the abominations that are done in its midst.", "bsb": "“Go throughout the city of Jerusalem,” said the LORD, “and put a mark on the foreheads of the men sighing and groaning over all the abominations committed there.”", "asv": "And Jehovah said unto him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry over all the abominations that are done in the midst thereof.", "ylt": "And He calleth unto the man who is clothed with linen, who hath the scribe's inkhorn at his loins, and Jehovah saith unto him, `Pass on into the midst of the city, into the midst of Jerusalem, and thou hast made a mark on the foreheads of the men who are sighing and who are groaning for all the abominations that are done in its midst.'", "dra": "And the Lord said to him: Go through the midst of the city, through the midst of Jerusalem: and mark Thau upon the foreheads of the men that sigh, and mourn for all the abominations that are committed in the midst thereof.", "bbe": "The Lord said to him, Go through the town, through the middle of Jerusalem, and put a mark on the brows of the men who are sorrowing and crying for all the disgusting things which are done in it.", "geneva": "And the Lord said vnto him, Goe through the middes of the citie, euen through the middes of Ierusalem and set a marke vpon the foreheads of them that mourne, and cry for all the abominations that be done in the middes thereof.", "wycliffe": "And the Lord seide to hym, Passe thou bi the myddis of the citee, in the myddis of Jerusalem, and marke thou Thau on the forhedis of men weilynge and sorewynge on alle abhomynaciouns that ben doon in the myddis therof.", "rotherham": "Then said Yahweh unto him. Pass along through the midst of the city, through the midst of Jerusalem,—and set thou a mark upon the foreheads of the men who are sighing and crying over all the abominations that are being done in her midst.", "darby": "and Jehovah said unto him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that are done in the midst thereof.", "twenty": "", "jps": "And HaShem said unto him: 'Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that are done in the midst thereof.'", "acv": "And Jehovah said to him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men who sigh and who cry over all the abominations that are done in the midst of it.", "anderson": "", "haweis": "", "noyes": "and Jehovah said to him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that wail for all the abominations that are done in the midst thereof.", "webster": "And the LORD said to him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that are done in the midst of it.", "vulgate": "et dixit Dominus ad eum transi per mediam civitatem in medio Hierusalem et signa thau super frontes virorum gementium et dolentium super cunctis abominationibus quae fiunt in medio eius;", "brenton": "And said to him, Go through the midst of Jerusalem, and set a mark on the foreheads of the men that groan and that grieve for all the iniquities that are done in the midst of them."}}, {"v": 5, "ref": "9:5", "o": "וּ/לְ/אֵ֨לֶּה֙ אָמַ֣ר בְּ/אָזְנַ֔/י עִבְר֥וּ בָ/עִ֛יר אַחֲרָ֖י/ו וְ/הַכּ֑וּ על אַל תָּחֹ֥ס עיני/כם עֵינְ/כֶ֖ם וְ/אַל תַּחְמֹֽלוּ", "en": {"kjv": "And to the others he said in mine hearing, Go ye after him through the city, and smite: let not your eye spare, neither have ye pity:", "web": "To the others he said in my hearing, Go through the city after him, and strike: don’t let your eye spare, neither have pity;", "bsb": "And as I listened, He said to the others, “Follow him through the city and start killing; do not show pity or spare anyone!", "asv": "And to the others he said in my hearing, Go ye through the city after him, and smite: let not your eye spare, neither have ye pity;", "ylt": "And to the others he said in mine ears, `Pass on into the city after him, and smite; your eye doth not pity, nor do ye spare;", "dra": "And to the others he said in my hearing: Go ye after him through the city, and strike: let not your eyes spare, nor be ye moved with pity.", "bbe": "And to these he said in my hearing, Go through the town after him using your axes: do not let your eyes have mercy, and have no pity:", "geneva": "And to the other he said, that I might heare, Goe ye after him through the citie, and smite: let your eye spare none, neither haue pitie.", "wycliffe": "And he seide to hem in myn heryng, Go ye thorouy the citee, and sue ye hym, and smytte ye; youre iye spare not, nether do ye merci.", "rotherham": "But unto these, said he in mine ears, Pass along through the city after him and smite,—let not your eye, shield, neither have ye pity:", "darby": "And to the others he said in my hearing, Go after him through the city, and smite: let not your eye spare, neither have pity.", "twenty": "", "jps": "And to the others He said in my hearing: 'Go ye through the city after him, and smite; let not your eye spare, neither have ye pity;", "acv": "And to the others he said in my hearing, Go ye through the city after him, and smite. Let not your eye spare, nor have ye pity.", "anderson": "", "haweis": "", "noyes": "And to the others he said, in my hearing, Go ye after him through the city, and smite! let not your eyes spare, neither have ye pity!", "webster": "And to the others he said in my hearing, Go ye after him through the city, and smite: let not your eye spare, neither have ye pity:", "vulgate": "et illis dixit audiente me transite per civitatem sequentes eum et percutite non parcat oculus vester neque misereamini;", "brenton": "And he said to the first in my hearing, Go after him into the city, and smite: and let not your eyes spare, and have no mercy."}}, {"v": 6, "ref": "9:6", "o": "זָקֵ֡ן בָּח֣וּר וּ/בְתוּלָה֩ וְ/טַ֨ף וְ/נָשִׁ֜ים תַּהַרְג֣וּ לְ/מַשְׁחִ֗ית וְ/עַל כָּל אִ֨ישׁ אֲשֶׁר עָלָ֤י/ו הַ/תָּו֙ אַל תִּגַּ֔שׁוּ וּ/מִ/מִּקְדָּשִׁ֖/י תָּחֵ֑לּוּ וַ/יָּחֵ֨לּוּ֙ בָּ/אֲנָשִׁ֣ים הַ/זְּקֵנִ֔ים אֲשֶׁ֖ר לִ/פְנֵ֥י הַ/בָּֽיִת", "en": {"kjv": "Slay utterly old and young, both maids, and little children, and women: but come not near any man upon whom is the mark; and begin at my sanctuary. Then they began at the ancient men which were before the house.", "web": "kill utterly the old man, the young man and the virgin, and little children and women; but don’t come near any man on whom is the mark: and begin at my sanctuary. Then they began at the old men that were before the house.", "bsb": "Slaughter the old men, the young men and maidens, the women and children; but do not go near anyone who has the mark. Now begin at My sanctuary.” So they began with the elders who were before the temple.", "asv": "slay utterly the old man, the young man and the virgin, and little children and women; but come not near any man upon whom is the mark: and begin at my sanctuary. Then they began at the old men that were before the house.", "ylt": "aged, young man, and virgin, and infant, and women, ye do slay--to destruction; and against any man on whom is the mark ye do not go nigh, and from My sanctuary ye begin.'", "dra": "Utterly destroy old and young, maidens, children and women: but upon whomsoever you shall see Thau, kill him not, and begin ye at my sanctuary. So they began at the ancient men who were before the house.", "bbe": "Give up to destruction old men and young men and virgins, little children and women: but do not come near any man who has the mark on him: and make a start at my holy place. So they made a start with the old men who were before the house.", "geneva": "Destroy vtterly the old, and the yong, and the maides, and the children, and the women, but touch no man, vpon whome is the marke, and begin at my Sanctuarie. Then they began at the Ancient men, which were before the house.", "wycliffe": "Sle ye til to deth, an eld man, a yong man, and a virgyn, a litil child, and wymmen; but sle ye not ony man, on whom ye seen Thau; and bigynne ye at my seyntuarie. Therfore thei bigunnen at the eldere men, that weren bifore the face of the hous.", "rotherham": "elder, young man and virgin and little ones and women, shall ye slay utterly, but unto any man who hath upon him the mark, do not ye come near, and at my sanctuary, shall ye begin. So they began with the elder men. who were before the house.", "darby": "Slay utterly the old man, the young man, and the maiden, and little children, and women; but come not near any man upon whom is the mark; and begin at my sanctuary. Then they began at the elders who were before the house.", "twenty": "", "jps": "slay utterly the old man, the young man and the maiden, and little children and women; but come not near any man upon whom is the mark; and begin at My sanctuary.' Then they began at the elders that were before the house.", "acv": "Kill utterly the old man, the young man, and the virgin, and little sons, and women, but come not near any man upon whom is the mark. And begin at my sanctuary. Then they began at the old men who were before the house.", "anderson": "", "haweis": "", "noyes": "The old man, the youth, the virgin, little children and women, slay and destroy; but come not near any one upon whom is the mark; and begin at my sanctuary. Then began they at the elders that were before the house.", "webster": "Slay utterly old [and] young, both maids, and little children, and women: but come not near any man upon whom [is] the mark; and begin at my sanctuary. Then they began at the elderly men who [were] before the house.", "vulgate": "senem adulescentulum et virginem parvulum et mulieres interficite usque ad internicionem omnem autem super quem videritis thau ne occidatis et a sanctuario meo incipite coeperunt ergo a viris senioribus qui erant ante faciem domus;", "brenton": "Slay utterly old man and youth, and virgin, and infants, and women: but go ye not nigh any on whom is the mark: begin at my sanctuary. So they began with the elder men who were within in the house."}}, {"v": 7, "ref": "9:7", "o": "וַ/יֹּ֨אמֶר אֲלֵי/הֶ֜ם טַמְּא֣וּ אֶת הַ/בַּ֗יִת וּ/מַלְא֧וּ אֶת הַ/חֲצֵר֛וֹת חֲלָלִ֖ים צֵ֑אוּ וְ/יָצְא֖וּ וְ/הִכּ֥וּ בָ/עִֽיר", "en": {"kjv": "And he said unto them, Defile the house, and fill the courts with the slain: go ye forth. And they went forth, and slew in the city.", "web": "He said to them, “Defile the house, and fill the courts with the slain. Go out!” They went out, and struck in the city.", "bsb": "Then He told them, “Defile the temple and fill the courts with the slain. Go forth!” So they went out and began killing throughout the city.", "asv": "And he said unto them, Defile the house, and fill the courts with the slain: go ye forth. And they went forth, and smote in the city.", "ylt": "And they begin among the aged men who are before the house, and He saith unto them, `Defile the house, and fill the courts with the wounded, go forth.' And they have gone forth and have smitten in the city.", "dra": "And he said to them: Defile the house, and fill the courts with the slain: go ye forth. And they went forth, and slew them that were in the city.", "bbe": "And he said to them, Make the house unclean, make the open places full of dead: go forward and send destruction on the town.", "geneva": "And he sayde vnto them, Defile the house, and fill the courtes with the slaine, then goe foorth: and they went out, and slewe them in the citie.", "wycliffe": "And he seide to hem, Defoule ye the hous, and fille ye the hallis with slayn men; go ye out. And thei yeden out, and killiden hem that weren in the citee.", "rotherham": "And he said unto them Defile ye the house and fill the courts with the slain,—go ye forth! So they went forth and smote in the city.", "darby": "And he said unto them, Defile the house, and fill the courts with the slain: go forth. And they went forth, and smote in the city.", "twenty": "", "jps": "And He said unto them: 'Defile the house, and fill the courts with the slain; go ye forth.' And they went forth, and smote in the city.", "acv": "And he said to them, Defile the house, and fill the courts with the slain. Go ye forth. And they went forth, and smote in the city.", "anderson": "", "haweis": "", "noyes": "And he said to them, Pollute the house, and fill the courts with the slain, then go ye forth. And they went forth, and slew in the city.", "webster": "And he said to them, Defile the house, and fill the courts with the slain: go ye forth. And they went forth, and slew in the city.", "vulgate": "et dixit ad eos contaminate domum et implete atria interfectis egredimini et egressi sunt et percutiebant eos qui erant in civitate;", "brenton": "And he said to them, Defile the house, and go out and fill the ways with dead bodies, and smite."}}, {"v": 8, "ref": "9:8", "o": "וַֽ/יְהִי֙ כְּ/הַכּוֹתָ֔/ם וְ/נֵֽאשֲׁאַ֖ר אָ֑נִי וָ/אֶפְּלָ֨/ה עַל פָּנַ֜/י וָ/אֶזְעַ֗ק וָֽ/אֹמַר֙ אֲהָהּ֙ אֲדֹנָ֣/י יְהוִ֔ה הֲ/מַשְׁחִ֣ית אַתָּ֗ה אֵ֚ת כָּל שְׁאֵרִ֣ית יִשְׂרָאֵ֔ל בְּ/שָׁפְכְּ/ךָ֥ אֶת חֲמָתְ/ךָ֖ עַל יְרוּשָׁלִָֽם", "en": {"kjv": "And it came to pass, while they were slaying them, and I was left, that I fell upon my face, and cried, and said, Ah Lord God! wilt thou destroy all the residue of Israel in thy pouring out of thy fury upon Jerusalem?", "web": "While they were killing, and I was left, I fell on my face, and cried, and said, “Ah Lord Yahweh! will you destroy all the residue of Israel in your pouring out of your wrath on Jerusalem?”", "bsb": "While they were killing, I was left alone. And I fell facedown and cried out, “Oh, Lord GOD, when You pour out Your wrath on Jerusalem, will You destroy the entire remnant of Israel?”", "asv": "And it came to pass, while they were smiting, and I was left, that I fell upon my face, and cried, and said, Ah Lord Jehovah! wilt thou destroy all the residue of Israel in thy pouring out of thy wrath upon Jerusalem?", "ylt": "And it cometh to pass, as they are smiting, and I--I am left--that I fall on my face, and cry, and say, `Ah, Lord Jehovah, art Thou destroying all the remnant of Israel, in Thy pouring out Thy wrath on Jerusalem?'", "dra": "And the slaughter being ended I was left; and I fell upon my face, and crying, I said: Alas, alas, alas, O Lord God, wilt thou then destroy all the remnant of Israel, by pouring out thy fury upon Jerusalem?", "bbe": "Now while they were doing so, and I was untouched, I went down on my face, and crying out, I said, Ah, Lord! will you give all the rest of Israel to destruction in letting loose your wrath on Jerusalem?", "geneva": "Nowe when they had slaine them, and I had escaped, I fell downe vpon my face, and cryed, saying, Ah Lord God, wilt thou destroy all the residue of Israel, in powring out thy wrath vpon Ierusalem?", "wycliffe": "And lo! whanne the sleyng was fillid, Y was left. And Y felle doun on my face, and Y criede, and seide, Alas! alas! alas! Lord God, therfor whether thou schalt leese alle remenauntis of Israel, and schalt schede out thi stronge veniaunce on Jerusalem?", "rotherham": "And it came to pass, while they were smiting them—I being left remaining, that I fell upon my face and made outcry, and said Alas! My Lord. Yahweh art thou about to destroy all the remnant of Israel, in that thou art pouring out of thine indignation upon Jerusalem?", "darby": "And it came to pass, while they were smiting, and I was left, that I fell upon my face, and cried, and said, Ah, Lord Jehovah! wilt thou destroy all the remnant of Israel in thy pouring out of thy fury upon Jerusalem?", "twenty": "", "jps": "And it came to pass, while they were smiting, and I was left, that I fell upon my face, and cried, and said: 'Ah L-rd GOD! wilt Thou destroy all the residue of Israel in Thy pouring out of Thy fury upon Jerusalem?'", "acv": "And it came to pass, while they were smiting, and I was left, that I fell upon my face, and cried, and said, Ah lord Jehovah! Will thou destroy all the residue of Israel in thy pouring out of thy wrath upon Jerusalem?", "anderson": "", "haweis": "", "noyes": "And while they were smiting them, I alone was left; and I fell upon my face, and cried, and said, Ah, Lord Jehovah! wilt thou destroy all the remnant of Israel, while thou pourest out thy fury upon Jerusalem?", "webster": "And it came to pass, while they were slaying them, and I was left, that I fell upon my face, and cried, and said, Ah Lord GOD! wilt thou destroy all the residue of Israel in thy pouring out of thy fury upon Jerusalem?", "vulgate": "et caede conpleta remansi ego ruique super faciem meam et clamans aio heu heu heu Domine Deus ergone disperdes omnes reliquias Israhel effundens furorem tuum super Hierusalem;", "brenton": "And it came to pass as they were smiting, that I fell upon my face, and cried out, and said, Alas, O Lord! wilt thou destroy the remnant of Israel, in pouring out thy wrath upon Jerusalem?"}}, {"v": 9, "ref": "9:9", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י עֲוֺ֨ן בֵּֽית יִשְׂרָאֵ֤ל וִֽ/יהוּדָה֙ גָּדוֹל֙ בִּ/מְאֹ֣ד מְאֹ֔ד וַ/תִּמָּלֵ֤א הָ/אָ֨רֶץ֙ דָּמִ֔ים וְ/הָ/עִ֖יר מָלְאָ֣ה מֻטֶּ֑ה כִּ֣י אָמְר֗וּ עָזַ֤ב יְהוָה֙ אֶת הָ/אָ֔רֶץ וְ/אֵ֥ין יְהוָ֖ה רֹאֶֽה", "en": {"kjv": "Then said he unto me, The iniquity of the house of Israel and Judah is exceeding great, and the land is full of blood, and the city full of perverseness: for they say, The Lord hath forsaken the earth, and the Lord seeth not.", "web": "Then he said to me, “The iniquity of the house of Israel and Judah is exceedingly great, and the land is full of blood, and the city full of perversion: for they say, ‘Yahweh has forsaken the land, and Yahweh doesn’t see.’", "bsb": "He replied, “The iniquity of the house of Israel and Judah is exceedingly great. The land is full of bloodshed, and the city is full of perversity. For they say, ‘The LORD has forsaken the land; the LORD does not see.’", "asv": "Then said he unto me, The iniquity of the house of Israel and Judah is exceeding great, and the land is full of blood, and the city full of wresting of judgment: for they say, Jehovah hath forsaken the land, and Jehovah seeth not.", "ylt": "And He saith unto me, `The iniquity of the house of Israel and Judah is very very great, and the land is full of blood, and the city hath been full of perverseness, for they have said: Jehovah hath forsaken the land, and Jehovah is not seeing.", "dra": "And he said to me: The iniquity of the house of Israel, and of Juda, is exceeding great, and the land is filled with blood, and the city is filled with perverseness: for they have said: The Lord hath forsaken the earth, and the Lord seeth not.", "bbe": "Then he said to me, The sin of the children of Israel and Judah is very, very great, and the land is full of blood and the town full of evil ways: for they say, The Lord has gone away from the land, and the Lord does not see.", "geneva": "Then saide he vnto me, The iniquitie of the house of Israel, and Iudah is exceeding great, so that the lande is full of blood, and the citie full of corrupt iudgement: for they say, The Lord hath forsaken the earth, and the Lord seeth vs not.", "wycliffe": "And he seide to me, The wickidnesse of the hous of Israel and of Juda is ful greet, and the lond is fillid of bloodis, and the citee is fillid with turnyng awei; for thei seiden, The Lord hath forsake the lond, and the Lord seeth not.", "rotherham": "And he said unto me the iniquity of the house of Israel and Judah, is exceeding, great, and the land is filled with shed blood, and the city is full of over-reaching,—for they have said. Yahweh hath forsaken the land,— and Yahweh doth not see.", "darby": "And he said unto me, The iniquity of the house of Israel and Judah is exceeding great, and the land is full of blood, and the city full of perverseness; for they say, Jehovah hath forsaken the earth, and Jehovah seeth not.", "twenty": "", "jps": "Then said He unto me: 'The iniquity of the house of Israel and Judah is exceeding great, and the land is full of blood, and the city full of wresting of judgment; for they say: HaShem hath forsaken the land, and HaShem seeth not.", "acv": "Then he said to me, The iniquity of the house of Israel and Judah is exceedingly great, and the land is full of blood, and the city full of perverseness. For they say, Jehovah has forsaken the land, and Jehovah does not see.", "anderson": "", "haweis": "", "noyes": "And he said to me: The iniquity of the house of Israel and Judah is exceedingly great, and the land is full of blood, and the city full of perverseness. For they say, \"Jehovah hath forsaken the land\"; and, \"Jehovah seeth not.\"", "webster": "Then said he to me, The iniquity of the house of Israel and Judah [is] exceeding great, and the land [is] full of blood, and the city full of perverseness: for they say, The LORD hath forsaken the earth, and the LORD seeth not.", "vulgate": "et dixit ad me iniquitas domus Israhel et Iuda magna est nimis valde et repleta est terra sanguinibus et civitas repleta est aversione dixerunt enim dereliquit Dominus terram et Dominus non videt;", "brenton": "Then said he to me, The iniquity of the house of Israel and Juda is become very exceedingly great: for the land is filled with many nations, and the city is filled with iniquity and uncleanness: because they have said, The Lord has forsaken the earth, The Lord looks not upon it."}}, {"v": 10, "ref": "9:10", "o": "וְ/גַ֨ם אֲנִ֔י לֹא תָח֥וֹס עֵינִ֖/י וְ/לֹ֣א אֶחְמֹ֑ל דַּרְכָּ֖/ם בְּ/רֹאשָׁ֥/ם נָתָֽתִּי", "en": {"kjv": "And as for me also, mine eye shall not spare, neither will I have pity, but I will recompense their way upon their head.", "web": "As for me also, my eye shall not spare, neither will I have pity, but I will bring their way on their head.”", "bsb": "But as for Me, I will not look on them with pity, nor will I spare them. I will bring their deeds down upon their own heads.”", "asv": "And as for me also, mine eye shall not spare, neither will I have pity, but I will bring their way upon their head.", "ylt": "And I also, Mine eye doth not pity, nor do I spare; their way on their own head I have put.'", "dra": "Therefore neither shall my eye spare, nor will I have pity: I will requite their way upon their head.", "bbe": "And as for me, my eye will not have mercy, and I will have no pity, but I will send the punishment of their ways on their heads.", "geneva": "As touching me also, mine eye shall not spare them, neither will I haue pitie, but will recompence their wayes vpon their heades.", "wycliffe": "Therfor and myn iye schal not spare, nether Y schal do merci; Y schal yelde the weie of hem on the heed of hem.", "rotherham": "Therefore as for even me, Mine eye shall not shield. Neither will I pity,— Their way upon their own head, have I rendered.", "darby": "And as for me also, mine eye shall not spare, neither will I have pity: I will recompense their way upon their head.", "twenty": "", "jps": "And as for Me also, Mine eye shall not spare, neither will I have pity, but I will bring their way upon their head.'", "acv": "And as for me also, my eye shall not spare, nor will I have pity, but I will bring their way upon their head.", "anderson": "", "haweis": "", "noyes": "Therefore mine eye shall not spare, neither will I have pity. Their way will I recompense upon their head.", "webster": "And as for me also, my eye shall not spare, neither will I have pity, [but] I will recompense their way upon their head.", "vulgate": "igitur et meus non parcet oculus neque miserebor viam eorum super caput eorum reddam;", "brenton": "Therefore mine eye shall not spare, neither will I have any mercy: I have recompensed their ways upon their heads."}}, {"v": 11, "ref": "9:11", "o": "וְ/הִנֵּ֞ה הָ/אִ֣ישׁ לְבֻ֣שׁ הַ/בַּדִּ֗ים אֲשֶׁ֤ר הַ/קֶּ֨סֶת֙ בְּ/מָתְנָ֔י/ו מֵשִׁ֥יב דָּבָ֖ר לֵ/אמֹ֑ר עָשִׂ֕יתִי כ/אשר כְּ/כֹ֖ל אֲשֶׁ֥ר צִוִּיתָֽ/נִי", "en": {"kjv": "And, behold, the man clothed with linen, which had the inkhorn by his side, reported the matter, saying, I have done as thou hast commanded me.", "web": "Behold, the man clothed in linen, who had the inkhorn by his side, reported the matter, saying, “I have done as you have commanded me.”", "bsb": "Then the man clothed in linen with the writing kit at his side reported back, “I have done as You commanded.”", "asv": "And, behold, the man clothed in linen, who had the inkhorn by his side, reported the matter, saying, I have done as thou hast commanded me.", "ylt": "And lo, the man clothed with linen, at whose loins is the inkhorn, is bringing back word, saying, `I have done as Thou hast commanded me.'", "dra": "And behold the man that was clothed with linen, that had the inkhorn at his back, returned the word, saying: I have done as thou hast commanded me.", "bbe": "Then the man clothed in linen, who had the inkpot at his side, came back and said, I have done what you gave me orders to do.", "geneva": "And beholde, the man clothed with linen which had the ynkhorne by his side, made report, and saide, Lord, I haue done as thou hast commanded me.", "wycliffe": "And lo! the man that was clothid in lynun clothis, that hadde a pennere in his bak, answeride a word, and seide, Y haue do, as thou comaundidist to me.", "rotherham": "And lo! the man clothed in linen, having the ink-holder by his side, bringing back word saying,— I have done according to all which thou didst command me.", "darby": "And behold, the man clothed with linen, who had the ink-horn by his side, reported the matter, saying, I have done as thou hast commanded me.", "twenty": "", "jps": "And, behold, the man clothed in linen, who had the inkhorn on his side, reported, saying: 'I have done according to all that Thou hast commanded me.'", "acv": "And, behold, the man clothed in linen, who had the writing case by his side, reported the matter, saying, I have done as thou have commanded me.", "anderson": "", "haweis": "", "noyes": "And lo, the man clothed with linen, who had the ink-horn by his side, returned answer, saying, I have done as thou hast commanded me.", "webster": "And behold, the man clothed with linen, who [had] the inkhorn by his side, reported the matter, saying, I have done as thou hast commanded me.", "vulgate": "et ecce vir qui indutus erat lineis qui habebat atramentarium in dorso suo respondit verbum dicens feci sicut praecepisti mihi;", "brenton": "And, behold, the man clothed with the long robe, and girt with the girdle about his loins, answered and said, I have done as thou didst command me."}}]}, {"c": 10, "verses": [{"v": 1, "ref": "10:1", "o": "וָ/אֶרְאֶ֗ה וְ/הִנֵּ֤ה אֶל הָ/רָקִ֨יעַ֙ אֲשֶׁר֙ עַל רֹ֣אשׁ הַ/כְּרֻבִ֔ים כְּ/אֶ֣בֶן סַפִּ֔יר כְּ/מַרְאֵ֖ה דְּמ֣וּת כִּסֵּ֑א נִרְאָ֖ה עֲלֵי/הֶֽם", "en": {"kjv": "Then I looked, and, behold, in the firmament that was above the head of the cherubims there appeared over them as it were a sapphire stone, as the appearance of the likeness of a throne.", "web": "Then I looked, and see, in the expanse that was over the head of the cherubim there appeared above them as it were a sapphire stone, as the appearance of the likeness of a throne.", "bsb": "And I looked and saw above the expanse, above the heads of the cherubim, the likeness of a throne of sapphire.", "asv": "Then I looked, and, behold, in the firmament that was over the head of the cherubim there appeared above them as it were a sapphire stone, as the appearance of the likeness of a throne.", "ylt": "And I look, and lo, on the expanse that is above the head of the cherubs, as a sapphire stone, as the appearance of the likeness of a throne, He hath been seen over them.", "dra": "And I saw and behold in the firmament that was over the heads of the cherubims, there appeared over them as it were the sapphire stone, as the appearance of the likeness of a throne.", "bbe": "Then looking, I saw that on the arch which was over the head of the winged ones there was seen over them what seemed like a sapphire stone, having the form of a king's seat.", "geneva": "And as I looked, beholde, in the firmament that was aboue the head of the Cherubims there appeared vpon them like vnto the similitude of a throne, as it were a saphir stone.", "wycliffe": "And Y siy, and lo! in the firmament that was on the heed of cherubyns, as a saphir stoon, and as the fourme of licnesse of a kyngis seete apperide theron.", "rotherham": "Then looked I and lo! in the expanse which was over the head of the cherubim as a sapphire stone, as the appearance of the likeness of a throne, appeared over them.", "darby": "And I looked, and behold, in the expanse that was over the head of the cherubim there appeared above them as it were a sapphire stone, as the appearance of the likeness of a throne.", "twenty": "", "jps": "Then I looked, and, behold, upon the firmament that was over the head of the cherubim, there appeared above them as it were a sapphire stone, as the appearance of the likeness of a throne.", "acv": "Then I looked, and, behold, in the firmament that was over the head of the cherubim there appeared above them as it were a sapphire stone, as the appearance of the likeness of a throne.", "anderson": "", "haweis": "", "noyes": "Then I looked, and lo, in the firmament that was above the head of the cherubs there appeared over them as it were a sapphire-stone, in form like a throne;", "webster": "Then I looked, and behold, in the firmament that was above the head of the cherubim there appeared over them as it were a sapphire stone, as the appearance of the likeness of a throne.", "vulgate": "et vidi et ecce in firmamento quod erat super caput cherubin quasi lapis sapphyrus quasi species similitudinis solii apparuit super ea;", "brenton": "Then I looked, and, behold, over the firmament that was above the head of the cherubs there was a likeness of a throne over them, as a sapphire stone."}}, {"v": 2, "ref": "10:2", "o": "וַ/יֹּ֜אמֶר אֶל הָ/אִ֣ישׁ לְבֻ֣שׁ הַ/בַּדִּ֗ים וַ/יֹּ֡אמֶר בֹּא֩ אֶל בֵּינ֨וֹת לַ/גַּלְגַּ֜ל אֶל תַּ֣חַת לַ/כְּר֗וּב וּ/מַלֵּ֨א חָפְנֶ֤י/ךָ גַֽחֲלֵי אֵשׁ֙ מִ/בֵּינ֣וֹת לַ/כְּרֻבִ֔ים וּ/זְרֹ֖ק עַל הָ/עִ֑יר וַ/יָּבֹ֖א לְ/עֵינָֽ/י", "en": {"kjv": "And he spake unto the man clothed with linen, and said, Go in between the wheels, even under the cherub, and fill thine hand with coals of fire from between the cherubims, and scatter them over the city. And he went in in my sight.", "web": "He spoke to the man clothed in linen, and said, Go in between the whirling wheels, even under the cherub, and fill both your hands with coals of fire from between the cherubim, and scatter them over the city. He went in as I watched.", "bsb": "And the LORD said to the man clothed in linen, “Go inside the wheelwork beneath the cherubim. Fill your hands with burning coals from among the cherubim and scatter them over the city.” And as I watched, he went in.", "asv": "And he spake unto the man clothed in linen, and said, Go in between the whirling wheels, even under the cherub, and fill both thy hands with coals of fire from between the cherubim, and scatter them over the city. And he went in in my sight.", "ylt": "And He speaketh unto the man clothed with linen, and saith, `Go in unto the midst of the wheel, unto the place of the cherub, and fill thy hands with coals of fire from between the cherubs, and scatter over the city.' And he goeth in before mine eyes.", "dra": "And he spoke to the man, that was clothed with linen, and said: Go in between the wheels that are under the cherubims and fill thy hand with the coals of fire that are between the cherubims, and pour them out upon the city. And he went in, in my sight:", "bbe": "And he said to the man clothed in linen, Go in between the wheels, under the winged ones, and get your two hands full of burning coals from between the winged ones and send them in a shower over the town. And he went in before my eyes.", "geneva": "And he spake vnto the man clothed with linen, and said, Go in betweene the wheeles, euen vnder the Cherub, and fill thine hands with coales of fire from betweene the Cherubims, and scatter the ouer the citie. And he went in in my sight.", "wycliffe": "And he seide to the man that was clothid in lynnun clothis, and spak, Entre thou in the myddis of wheelis, that ben vndur cherubyns, and fille thin hond with coolis of fier, that ben bitwixe cherubyns, and schede thou out on the citee.", "rotherham": "Then said he unto the man clothed in linen—then said he Go in between the whirling wheels, even under the cherub, and fill both thy hands with live coals of fire from between the cherubim, and throw over the city. So he went in before mine eyes.", "darby": "And he spoke unto the man clothed with linen, and said, Come in between the wheels, under the cherub, and fill the hollow of thy hands with coals of fire from between the cherubim, and scatter them over the city. And he went in in my sight.", "twenty": "", "jps": "And He spoke unto the man clothed in linen, and said: 'Go in between the wheelwork, even under the cherub, and fill both thy hands with coals of fire from between the cherubim, and dash them against the city.' And he went in in my sight.", "acv": "And he spoke to the man clothed in linen, and said, Go in between the whirling wheels, even under the cherub, and fill both thy hands with coals of fire from between the cherubim, and scatter them over the city. And he went in in my sight.", "anderson": "", "haweis": "", "noyes": "and He spake to the man that was clothed with linen, and said, Go in between the wheels under the cherub, and fill thy hands with coals of fire, which are between the cherubs, and scatter them over the city. And he went in before my eyes.", "webster": "And he spoke to the man clothed with linen, and said, Go in between the wheels, [even] under the cherub, and fill thy hand with coals of fire from between the cherubim, and scatter [them] over the city. And he entered in my sight.", "vulgate": "et dixit ad virum qui indutus erat lineis et ait ingredere in medio rotarum quae sunt subtus cherub et imple manum tuam prunis ignis quae sunt inter cherubin et effunde super civitatem ingressusque est in conspectu meo;", "brenton": "And he said to the man clothed with the long robe, Go in between the wheels that are under the cherubs, and fill thine hands with coals of fire from between the cherubs, and scatter them over the city. And he went in my sight."}}, {"v": 3, "ref": "10:3", "o": "וְ/הַ/כְּרֻבִ֗ים עֹֽמְדִ֛ים מִ/ימִ֥ין לַ/בַּ֖יִת בְּ/בֹא֣/וֹ הָ/אִ֑ישׁ וְ/הֶ/עָנָ֣ן מָלֵ֔א אֶת הֶ/חָצֵ֖ר הַ/פְּנִימִֽית", "en": {"kjv": "Now the cherubims stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "web": "Now the cherubim stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "bsb": "Now when the man went in, the cherubim were standing on the south side of the temple, and a cloud filled the inner court.", "asv": "Now the cherubim stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "ylt": "And the cherubs are standing on the right side of the house, at the going in of the man, and the cloud hath filled the inner court,", "dra": "And the cherubims stood on the right side of the house, when the man went in, and a cloud filled the inner court.", "bbe": "Now the winged ones were stationed on the right side of the house when the man went in; and the inner square was full of the cloud.", "geneva": "Now the Cherubims stood vpon the right side of the house, when the man went in, and the cloude filled the inner court.", "wycliffe": "And he entride in my siyt; forsothe cherubyns stoden at the riyt side of the hous, whanne the man entride, and a clowde fillide the ynnere halle.", "rotherham": "Now the cherubim were standing on the right side of the house when the man went in,—and, the, cloud filled the inner court,", "darby": "And the cherubim stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "twenty": "", "jps": "Now the cherubim stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "acv": "Now the cherubim stood on the right side of the house when the man went in, and the cloud filled the inner court.", "anderson": "", "haweis": "", "noyes": "Now the cherubs stood upon the right side of the house when the man went in; and the cloud filled the inner court.", "webster": "Now the cherubim stood on the right side of the house, when the man went in; and the cloud filled the inner court.", "vulgate": "cherubin autem stabant a dextris domus cum ingrederetur vir et nubes implevit atrium interius;", "brenton": "And the cherubs stood on the right hand of the house, as the man went in; and the cloud filled the inner court."}}, {"v": 4, "ref": "10:4", "o": "וַ/יָּ֤רָם כְּבוֹד יְהוָה֙ מֵ/עַ֣ל הַ/כְּר֔וּב עַ֖ל מִפְתַּ֣ן הַ/בָּ֑יִת וַ/יִּמָּלֵ֤א הַ/בַּ֨יִת֙ אֶת הֶ֣/עָנָ֔ן וְ/הֶֽ/חָצֵר֙ מָֽלְאָ֔ה אֶת נֹ֖גַהּ כְּב֥וֹד יְהוָֽה", "en": {"kjv": "Then the glory of the Lord went up from the cherub, and stood over the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of the Lord’s glory.", "web": "Yahweh’s glory mounted up from the cherub, and stood over the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of Yahweh’s glory.", "bsb": "Then the glory of the LORD rose from above the cherubim and stood over the threshold of the temple. The temple was filled with the cloud, and the court was filled with the brightness of the glory of the LORD.", "asv": "And the glory of Jehovah mounted up from the cherub, and stood over the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of Jehovah’s glory.", "ylt": "and become high doth the honour of Jehovah above the cherub, over the threshold of the house, and the house is filled with the cloud, and the court hath been filled with the brightness of the honour of Jehovah.", "dra": "And the glory of the Lord was lifted up from above the cherub to the threshold of the house: and the house was filled with the cloud, and the court was filled with the brightness of the glory of the Lord.", "bbe": "And the glory of the Lord went up from the winged ones and came to rest over the doorstep of the house; and the house was full of the cloud and the open square was full of the shining of the Lord's glory.", "geneva": "Then the glorie of the Lord went vp from the Cherub, and stoode ouer the doore of the house, and the house was filled with the cloud, and the court was filled with the brightnesse of the Lordes glorie.", "wycliffe": "And the glorie of the Lord was reisid fro aboue cherubyns to the threisfold of the hous; and the hous was fillid with a cloude, and the halle was fillid with schynyng of the glorie of the Lord.", "rotherham": "Then arose the glory of Yahweh from off the cherub, unto the threshold of the house,—and the house was filled with the cloud, and the, court, was filled with the brightness of the glory of Yahweh.", "darby": "And the glory of Jehovah mounted up from the cherub, [and came] over the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of Jehovah's glory.", "twenty": "", "jps": "And the glory of HaShem mounted up from the cherub to the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of HaShem'S glory.", "acv": "And the glory of Jehovah mounted up from the cherub, over the threshold of the house. And the house was filled with the cloud, and the court was full of the brightness of Jehovah's glory.", "anderson": "", "haweis": "", "noyes": "And the glory of Jehovah was lifted up from the cherub to the threshold of the house; and the house was filled with the cloud, and the court was filled with the brightness of the glory of Jehovah.", "webster": "Then the glory of the LORD went up from the cherub, [and stood] over the threshhold of the house; and the house was filled with the cloud, and the court was full of the brightness of the LORD'S glory.", "vulgate": "et elevata est gloria Domini desuper cherub ad limen domus et repleta est domus nube et atrium repletum est splendore gloriae Domini;", "brenton": "Then the glory of the Lord departed from the cherubs to the porch of the house; and the cloud filled the house, and the court was filled with the brightness of the glory of the Lord."}}, {"v": 5, "ref": "10:5", "o": "וְ/קוֹל֙ כַּנְפֵ֣י הַ/כְּרוּבִ֔ים נִשְׁמַ֕ע עַד הֶ/חָצֵ֖ר הַ/חִיצֹנָ֑ה כְּ/ק֥וֹל אֵל שַׁדַּ֖י בְּ/דַבְּרֽ/וֹ", "en": {"kjv": "And the sound of the cherubims’ wings was heard even to the outer court, as the voice of the Almighty God when he speaketh.", "web": "The sound of the wings of the cherubim was heard even to the outer court, as the voice of God Almighty when he speaks.", "bsb": "The sound of the wings of the cherubim could be heard as far as the outer court, like the voice of God Almighty when He speaks.", "asv": "And the sound of the wings of the cherubim was heard even to the outer court, as the voice of God Almighty when he speaketh.", "ylt": "And a noise of the wings of the cherubs hath been heard unto the outer court, as the voice of God--the Mighty One--in His speaking.", "dra": "And the sound of the wings of the cherubims was heard even to the outward court as the voice of God Almighty speaking.", "bbe": "And the sound of the wings of the winged ones was clear even in the outer square, like the voice of the Ruler of all.", "geneva": "And the sound of the Cherubims wings was heard into the vtter court, as the voyce of the Almightie God, when he speaketh.", "wycliffe": "And the sown of wyngis of cherubyns was herd til to the outermere halle, as the vois of almyyti God spekynge.", "rotherham": "And the sound of the wings of the cherubim was heard, as far as the outer court,—like the voice of the Almighty GOD when he speaketh,", "darby": "And the sound of the wings of the cherubim was heard to the outer court, as the voice of the AlmightyGod when he speaketh.", "twenty": "", "jps": "And the sound of the wings of the cherubim was heard even to the outer court, as the voice of G-d Almighty when He speaketh.", "acv": "And the sound of the wings of the cherubim was heard even to the outer court, as the voice of God Almighty when he speaks.", "anderson": "", "haweis": "", "noyes": "And the sound of the wings of the cherubs was heard even to the outer court, as the voice of God, the Almighty, when he speaketh.", "webster": "And the sound of the cherubim's wings was heard [even] to the outer court, as the voice of the Almighty God when he speaketh.", "vulgate": "et sonitus alarum cherubin audiebatur usque ad atrium exterius quasi vox Dei omnipotentis loquentis;", "brenton": "And the sound of the cherubs' wings was heard as far as the outer court, as the voice of the Almighty God speaking."}}, {"v": 6, "ref": "10:6", "o": "וַ/יְהִ֗י בְּ/צַוֺּת/וֹ֙ אֶת הָ/אִ֤ישׁ לְבֻֽשׁ הַ/בַּדִּים֙ לֵ/אמֹ֔ר קַ֥ח אֵשׁ֙ מִ/בֵּינ֣וֹת לַ/גַּלְגַּ֔ל מִ/בֵּינ֖וֹת לַ/כְּרוּבִ֑ים וַ/יָּבֹא֙ וַֽ/יַּעֲמֹ֔ד אֵ֖צֶל הָ/אוֹפָֽן", "en": {"kjv": "And it came to pass, that when he had commanded the man clothed with linen, saying, Take fire from between the wheels, from between the cherubims; then he went in, and stood beside the wheels.", "web": "It came to pass, when he commanded the man clothed in linen, saying, Take fire from between the whirling wheels, from between the cherubim, that he went in, and stood beside a wheel.", "bsb": "When the LORD commanded the man clothed in linen, saying, “Take fire from within the wheelwork, from among the cherubim,” the man went in and stood beside a wheel.", "asv": "And it came to pass, when he commanded the man clothed in linen, saying, Take fire from between the whirling wheels, from between the cherubim, that he went in, and stood beside a wheel.", "ylt": "And it cometh to pass, in His commanding the man clothed with linen, saying, `Take fire from between the wheel, from between the cherubs,' and he goeth in and standeth near the wheel,", "dra": "And when he had commanded the man that was clothed with linen, saying: Take fire from the midst of the wheels that are between the cherubims: he went in and stood beside the wheel.", "bbe": "And when he gave orders to the man clothed in linen, saying, Take fire from between the wheels, from between the winged ones, then he went in and took his place at the side of a wheel.", "geneva": "And when he had commanded the man clothed with linnen, saying, Take fire from betweene the wheeles, and from betweene ye Cherubims, then he went in and stood beside ye wheele.", "wycliffe": "And whanne he hadde comaundid to the man that was clothid in lynnun clothis, and hadde seid, Take thou fier fro the myddis of the wheelis, that ben bitwixe cherubyns, he entride, and stood bisidis the wheel.", "rotherham": "So then it came to pass— when he commanded the man clothed with linen, saying, Take fire from between the whirling wheels, from between the cherubim, then went he in and stood beside the wheel.", "darby": "And it came to pass when he had commanded the man clothed with linen, saying, Take fire from between the wheels, from between the cherubim, then he went in, and stood beside the wheel.", "twenty": "", "jps": "And it came to pass, when He commanded the man clothed in linen, saying: 'Take fire from between the wheelwork, from between the cherubim', that he went in, and stood beside a wheel.", "acv": "And it came to pass, when he commanded the man clothed in linen, saying, Take fire from between the whirling wheels, from between the cherubim, that he went in, and stood beside a wheel.", "anderson": "", "haweis": "", "noyes": "And when he commanded the man clothed with linen, saying, Take fire from between the wheels, from between the cherubs, he went in and stood beside the wheels.", "webster": "And it came to pass, [that] when he had commanded the man clothed with linen, saying, Take fire from between the wheels, from between the cherubim; then he went in, and stood beside the wheels.", "vulgate": "cumque praecepisset viro qui indutus erat lineis dicens sume ignem de medio rotarum quae sunt inter cherubin ingressus ille stetit iuxta rotam;", "brenton": "And it came to pass, when he gave a charge to the man clothed with the sacred robe, saying, Take fire from between the wheels from between the cherubs, that he went in, and stood near the wheels."}}, {"v": 7, "ref": "10:7", "o": "וַ/יִּשְׁלַח֩ הַ/כְּר֨וּב אֶת יָד֜/וֹ מִ/בֵּינ֣וֹת לַ/כְּרוּבִ֗ים אֶל הָ/אֵשׁ֙ אֲשֶׁר֙ בֵּינ֣וֹת הַ/כְּרֻבִ֔ים וַ/יִּשָּׂא֙ וַ/יִּתֵּ֔ן אֶל חָפְנֵ֖י לְבֻ֣שׁ הַ/בַּדִּ֑ים וַ/יִּקַּ֖ח וַ/יֵּצֵֽא", "en": {"kjv": "And one cherub stretched forth his hand from between the cherubims unto the fire that was between the cherubims, and took thereof, and put it into the hands of him that was clothed with linen: who took it, and went out.", "web": "The cherub stretched out his hand from between the cherubim to the fire that was between the cherubim, and took of it, and put it into the hands of him who was clothed in linen, who took it and went out.", "bsb": "Then one of the cherubim reached out his hand and took some of the fire that was among them. And he put it into the hands of the man clothed in linen, who received it and went out.", "asv": "And the cherub stretched forth his hand from between the cherubim unto the fire that was between the cherubim, and took thereof, and put it into the hands of him that was clothed in linen, who took it and went out.", "ylt": "that the one cherub putteth forth his hand from between the cherubs unto the fire that is between the cherubs, and lifteth up, and giveth into the hands of him who is clothed with linen, and he receiveth, and cometh forth.", "dra": "And one cherub stretched out his arm from the midst of the cherubims to the fire that was between the cherubims: and he took, and put it into the hands of him that was clothed with linen: who took it and went forth.", "bbe": "And stretching out his hand to the fire which was between the winged ones, he took some of it and went out.", "geneva": "And one Cherub stretched forth his hand from betweene the Cherubims vnto the fire, that was betweene the Cherubims, and tooke thereof, and put it into the hands of him that was clothed with linnen: who tooke it and went out.", "wycliffe": "And cherub stretchide forth his hond fro the myddis of cherubyns, to the fier that was bitwixe cherubyns; and took, and yaf in to the hondis of hym that was clothid in lynnun clothis; and he took, and yede out.", "rotherham": "And the cherub put forth his hand from between the cherubim unto the fire that was between the cherubim, and took up thereof and gave into the hands of him who was clothed with linen,—who took [it] and went forth,", "darby": "And the cherub stretched forth his hand from between the cherubim unto the fire that was between the cherubim, and took and put it into the hands of him [that was] clothed with linen; who took [it], and went out.", "twenty": "", "jps": "And the cherub stretched forth his hand from between the cherubim unto the fire that was between the cherubim, and took thereof, and put it into the hands of him that was clothed in linen, who took it and went out.", "acv": "And the cherub stretched forth his hand from between the cherubim to the fire that was between the cherubim, and took, and put it into the hands of him who was clothed in linen, who took it and went out.", "anderson": "", "haweis": "", "noyes": "And one cherub stretched forth his hand from between the cherubs to the fire that was between the cherubs, and took thereof, and put it into the hands of him that was clothed with linen, who took it, and went out.", "webster": "And [one] cherub stretched forth his hand from between the cherubim, to the fire that [was] between the cherubim, and took [of it], and put [it] into the hands of [him that was] clothed with linen: who took [it], and went out.", "vulgate": "et extendit cherub manum de medio cherubin ad ignem qui erat inter cherubin et sumpsit et dedit in manus eius qui indutus erat lineis qui accipiens egressus est;", "brenton": "And he stretched forth his hand into the midst of the fire that was between the cherubs, and took thereof, and put it into the hands of the man clothed with the sacred robe: and he took it, and went out."}}, {"v": 8, "ref": "10:8", "o": "וַ/יֵּרָ֖א לַ/כְּרֻבִ֑ים תַּבְנִית֙ יַד אָדָ֔ם תַּ֖חַת כַּנְפֵי/הֶֽם", "en": {"kjv": "And there appeared in the cherubims the form of a man’s hand under their wings.", "web": "There appeared in the cherubim the form of a man’s hand under their wings.", "bsb": "(The cherubim appeared to have the form of human hands under their wings.)", "asv": "And there appeared in the cherubim the form of a man’s hand under their wings.", "ylt": "And there appeareth in the cherubs the form of a hand of man under their wings,", "dra": "And there appeared in the cherubims the likeness of a man's hand under their wings.", "bbe": "And I saw the form of a man's hands among the winged ones under their wings.", "geneva": "And there appeared in the Cherubims, the likenesse of a mans hande vnder their wings.", "wycliffe": "And the licnesse of the hond of a man apperide in cherubyns, vndur the wyngis of tho.", "rotherham": "Now the cherubim appeared to have. the likeness of the hand of a man, under their wings.", "darby": "And there appeared in the cherubim the form of a man's hand under their wings.", "twenty": "", "jps": "And there appeared in the cherubim the form of a man's hand under their wings.", "acv": "And there appeared in the cherubim the form of a man's hand under their wings.", "anderson": "", "haweis": "", "noyes": "And there was seen in the cherubs the form of a man’s hand under their wings.", "webster": "And there appeared in the cherubim the form of a man's hand under their wings.", "vulgate": "et apparuit in cherubin similitudo manus hominis subtus pinnas eorum;", "brenton": "And I saw the cherubs having the likeness of men's hands under their wings."}}, {"v": 9, "ref": "10:9", "o": "וָ/אֶרְאֶ֗ה וְ/הִנֵּ֨ה אַרְבָּעָ֣ה אוֹפַנִּים֮ אֵ֣צֶל הַ/כְּרוּבִים֒ אוֹפַ֣ן אֶחָ֗ד אֵ֚צֶל הַ/כְּר֣וּב אֶחָ֔ד וְ/אוֹפַ֣ן אֶחָ֔ד אֵ֖צֶל הַ/כְּר֣וּב אֶחָ֑ד וּ/מַרְאֵה֙ הָ/א֣וֹפַנִּ֔ים כְּ/עֵ֖ין אֶ֥בֶן תַּרְשִֽׁישׁ", "en": {"kjv": "And when I looked, behold the four wheels by the cherubims, one wheel by one cherub, and another wheel by another cherub: and the appearance of the wheels was as the colour of a beryl stone.", "web": "I looked, and behold, four wheels beside the cherubim, one wheel beside one cherub, and another wheel beside another cherub; and the appearance of the wheels was like a beryl stone.", "bsb": "Then I looked and saw four wheels beside the cherubim, one wheel beside each cherub. And the wheels gleamed like a beryl stone.", "asv": "And I looked, and behold, four wheels beside the cherubim, one wheel beside one cherub, and another wheel beside another cherub; and the appearance of the wheels was like unto a beryl stone.", "ylt": "and I look, and lo, four wheels near the cherubs, one wheel near the one cherub, and another wheel near the other cherub, and the appearance of the wheels is as the colour of a beryl stone.", "dra": "And I saw, and behold there were four wheels by the cherubims: one wheel by one cherub, and another wheel by another cherub: and the appearance of the wheels was to the sight like the chrysolite stone:", "bbe": "And looking, I saw four wheels by the side of the winged ones, one wheel by the side of a winged one and another wheel by the side of another: and the wheels were like the colour of a beryl stone to the eye.", "geneva": "And when I looked vp, beholde, foure wheeles were beside the Cherubims, one wheele by one Cherub, and another wheele by another Cherub, and the appearance of the wheeles was as the colour of a Chrysolite stone.", "wycliffe": "And Y siy, and lo! foure wheelis weren bisidis cherubyns; o wheel bisidis o cherub, and another wheel bisidis another cherub; forsothe the licnesse of wheelis was as the siyt of the stoon crisolitis.", "rotherham": "Then looked I. and lo! four wheels by the cherubim—one wheel by one cherub, and another wheel by another cherub,—and the appearance of the wheels was to look upon like a Tarshish stone;", "darby": "And I looked, and behold, four wheels beside the cherubim, one wheel beside one cherub, and another wheel beside another cherub; and the appearance of the wheels was as the look of a chrysolite stone.", "twenty": "", "jps": "And I looked, and behold four wheels beside the cherubim, one wheel beside one cherub, and another wheel beside another cherub; and the appearance of the wheels was as the colour of a beryl stone.", "acv": "And I looked, and, behold, four wheels beside the cherubim, one wheel beside one cherub, and another wheel beside another cherub. And the appearance of the wheels was like a beryl stone.", "anderson": "", "haweis": "", "noyes": "And when I looked, behold, four wheels were by the cherubs, one wheel by one cherub, and another wheel by another cherub; and the appearance of the wheels was like that of a chrysolite.", "webster": "And when I looked, behold the four wheels by the cherubim, one wheel by one cherub, and another wheel by another cherub: and the appearance of the wheels [was] as the color of a beryl stone.", "vulgate": "et vidi et ecce quattuor rotae iuxta cherubin rota una iuxta cherub unum et rota alia iuxta cherub unum species autem erat rotarum quasi visio lapidis chrysoliti;", "brenton": "And I saw, and behold, four wheels stood by the cherubs, one wheel by each cherub: and the appearance of the wheels was as the appearance of a carbuncle stone."}}, {"v": 10, "ref": "10:10", "o": "וּ/מַ֨רְאֵי/הֶ֔ם דְּמ֥וּת אֶחָ֖ד לְ/אַרְבַּעְתָּ֑/ם כַּ/אֲשֶׁ֛ר יִהְיֶ֥ה הָ/אוֹפַ֖ן בְּ/ת֥וֹךְ הָ/אוֹפָֽן", "en": {"kjv": "And as for their appearances, they four had one likeness, as if a wheel had been in the midst of a wheel.", "web": "As for their appearance, the four of them had one likeness, like a wheel within a wheel.", "bsb": "As for their appearance, all four had the same form, like a wheel within a wheel.", "asv": "And as for their appearance, they four had one likeness, as if a wheel had been within a wheel.", "ylt": "As to their appearances, one likeness is to them four, as it were the wheel in the midst of the wheel.", "dra": "And as to their appearance, all four were alike: as if a wheel were in the midst of a wheel.", "bbe": "In form the four of them were all the same, they seemed like a wheel inside a wheel.", "geneva": "And their appearance (for they were all foure of one facion) was as if one wheele had bene in another wheele.", "wycliffe": "And the biholdyng of tho was o licnesse of foure, as if a wheel be in the myddis of a wheel.", "rotherham": "and as for their appearance, one likeness, had they four,-as might be a wheel in the midst of a wheel.", "darby": "And as for their appearance, they four had one likeness, as if a wheel were in the midst of a wheel.", "twenty": "", "jps": "And as for their appearance, they four had one likeness, as if a wheel had been within a wheel.", "acv": "And as for their appearance, those four had one likeness, as if a wheel have been within a wheel.", "anderson": "", "haweis": "", "noyes": "And as to their appearance, all four had one form, as if a wheel were in the midst of a wheel.", "webster": "And [as for] their appearances, they four had one likeness, as if a wheel had been in the midst of a wheel.", "vulgate": "et aspectus earum similitudo una quattuor quasi sit rota in medio rotae;", "brenton": "And as for their appearance, there was one likeness to the four, as if there should be a wheel in the midst of a wheel."}}, {"v": 11, "ref": "10:11", "o": "בְּ/לֶכְתָּ֗/ם אֶל אַרְבַּ֤עַת רִבְעֵי/הֶם֙ יֵלֵ֔כוּ לֹ֥א יִסַּ֖בּוּ בְּ/לֶכְתָּ֑/ם כִּ֣י הַ/מָּק֞וֹם אֲשֶׁר יִפְנֶ֤ה הָ/רֹאשׁ֙ אַחֲרָ֣י/ו יֵלֵ֔כוּ לֹ֥א יִסַּ֖בּוּ בְּ/לֶכְתָּֽ/ם", "en": {"kjv": "When they went, they went upon their four sides; they turned not as they went, but to the place whither the head looked they followed it; they turned not as they went.", "web": "When they went, they went in their four directions: they didn’t turn as they went, but to the place where the head looked they followed it; they didn’t turn as they went.", "bsb": "When they moved, they would go in any of the four directions, without turning as they moved. For wherever the head faced, the cherubim would go in that direction, without turning as they moved.", "asv": "When they went, they went in their four directions: they turned not as they went, but to the place whither the head looked they followed it; they turned not as they went.", "ylt": "In their going, on their four sides they go; they turn not round in their going, for to the place whither the head turneth, after it they go, they turn not round in their going.", "dra": "And when they went, they went by four ways: and they turned not when they went: but to the place whither they first turned, the rest also followed, and did not turn back.", "bbe": "When they were moving, they went on their four sides without turning; they went after the head in the direction in which it was looking; they went without turning.", "geneva": "When they went foorth, they went vpon their foure sides, and they returned not as they went: but to the place whither the first went, they went after it, and they turned not as they went.", "wycliffe": "And whanne tho yeden, tho yeden in to foure partis; tho turneden not ayen goynge, but to the place to which that that was the firste wheel bowide to go, also othere suyden, and turneden not ayen.", "rotherham": "When they went, upon their four sides, they went, they turned not when they went, for to the place whithersoever the head turned, after it, they went, they turned not when they went.", "darby": "When they went, they went upon their four sides; they turned not as they went, but to the place whither the head looked they followed it: they turned not as they went.", "twenty": "", "jps": "When they went, they went toward their four sides; they turned not as they went, but to the place whither the head looked they followed it; they turned not as they went.", "acv": "When they went, they went in their four directions. They did not turn as they went, but to the place where the head looked they followed it. They did not turn as they went.", "anderson": "", "haweis": "", "noyes": "When they went, they went upon their four sides; they turned not about when they went; but to the place whither the head looked they followed it, they turned not about when they went.", "webster": "When they went, they went upon their four sides; they turned not as they went, but to the place whither the head looked, they followed it; they turned not as they went.", "vulgate": "cumque ambularent in quattuor partes gradiebantur non revertebantur ambulantes sed ad locum ad quem ire declinabat quae prima erat sequebantur et ceterae nec convertebantur;", "brenton": "When they went, they went on their four sides; they turned not when they went, for whichever way the first head looked, they went; and they turned not as they went."}}, {"v": 12, "ref": "10:12", "o": "וְ/כָל בְּשָׂרָ/ם֙ וְ/גַבֵּ/הֶ֔ם וִֽ/ידֵי/הֶ֖ם וְ/כַנְפֵי/הֶ֑ם וְ/הָ/אֽוֹפַנִּ֗ים מְלֵאִ֤ים עֵינַ֨יִם֙ סָבִ֔יב לְ/אַרְבַּעְתָּ֖/ם אוֹפַנֵּי/הֶֽם", "en": {"kjv": "And their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes round about, even the wheels that they four had.", "web": "Their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes all around, even the wheels that the four of them had.", "bsb": "Their entire bodies, including their backs, hands, and wings, were full of eyes all around, as were their four wheels.", "asv": "And their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes round about, even the wheels that they four had.", "ylt": "And all their flesh, and their backs, and their hands, and their wings, and the wheels, are full of eyes round about; to them four are their wheels.", "dra": "And their whole body, and their necks, and their hands, and their wings, and the circles were full of eyes, round about the four wheels.", "bbe": "And the edges of the four wheels were full of eyes round about.", "geneva": "And their whole bodie, and their rings, and their hands, and their wings, and the wheeles were full of eyes round about, euen in the same foure wheeles.", "wycliffe": "And al the bodi of tho wheelis, and the neckis, and hondis, and wyngis of the beestis, and the cerclis, weren ful of iyen, in the cumpas of foure wheelis.", "rotherham": "And all their flesh, and their back, and their hands and their wings, and the wheels were full of eyes round about, even their wheels which they four had", "darby": "And their whole body, and their backs, and their hands, and their wings, and the wheels were full of eyes round about, in them four [and] their wheels.", "twenty": "", "jps": "And their whole body, and their backs, and their hands, and their wings, and the wheels were full of eyes round about, even the wheels that they four had.", "acv": "And their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes round about, even the wheels that those four had.", "anderson": "", "haweis": "", "noyes": "And their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes round about, even the wheels which they four had.", "webster": "And their whole body, and their backs, and their hands, and their wings, and the wheels, [were] full of eyes on every side, [even] the wheels that they four had.", "vulgate": "et omne corpus earum et colla et manus et pinnae et circuli plena erant oculis in circuitu quattuor rotarum;", "brenton": "And their backs, and their hands, and their wings, and the wheels, were full of eyes round about the four wheels."}}, {"v": 13, "ref": "10:13", "o": "לָ/א֖וֹפַנִּ֑ים לָ/הֶ֛ם קוֹרָ֥א הַ/גַּלְגַּ֖ל בְּ/אָזְנָֽ/י", "en": {"kjv": "As for the wheels, it was cried unto them in my hearing, O wheel.", "web": "As for the wheels, they were called in my hearing, the whirling wheels.", "bsb": "I heard the wheels being called “the whirling wheels.”", "asv": "As for the wheels, they were called in my hearing the whirling wheels.", "ylt": "To the wheels--to them is one calling in mine ears, `O wheel!'", "dra": "And these wheels he called voluble, in my hearing.", "bbe": "As for the wheels, they were named in my hearing, the circling wheels.", "geneva": "And the Cherub cryed to these wheeles in mine hearing, saying, O wheele.", "wycliffe": "And he clepide tho wheelis volible, ether able to go al aboute, in myn heryng.", "rotherham": "To the wheels—to them, was made the cry— O whirling wheel! in mine ears.", "darby": "As for the wheels, they were called in my hearing, Galgal.", "twenty": "", "jps": "As for the wheels, they were called in my hearing The wheelwork.", "acv": "As for the wheels, they were called in my hearing, O wheel.", "anderson": "", "haweis": "", "noyes": "And as to these wheels, each one of them in my hearing was called Whirlwind.", "webster": "As for the wheels, it was cried to them in my hearing, O wheel.", "vulgate": "et rotas istas vocavit volubiles audiente me;", "brenton": "And these wheels were called Gelgel in my hearing."}}, {"v": 14, "ref": "10:14", "o": "וְ/אַרְבָּעָ֥ה פָנִ֖ים לְ/אֶחָ֑ד פְּנֵ֨י הָ/אֶחָ֜ד פְּנֵ֣י הַ/כְּר֗וּב וּ/פְנֵ֤י הַ/שֵּׁנִי֙ פְּנֵ֣י אָדָ֔ם וְ/הַ/שְּׁלִישִׁי֙ פְּנֵ֣י אַרְיֵ֔ה וְ/הָ/רְבִיעִ֖י פְּנֵי נָֽשֶׁר", "en": {"kjv": "And every one had four faces: the first face was the face of a cherub, and the second face was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "web": "Every one had four faces: the first face was the face of the cherub, and the second face was the face of a man, and the third face the face of a lion, and the fourth the face of an eagle.", "bsb": "Each of the cherubim had four faces: the first face was that of a cherub, the second that of a man, the third that of a lion, and the fourth that of an eagle.", "asv": "And every one had four faces: the first face was the face of the cherub, and the second face was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "ylt": "And four faces are to each; the face of the one is the face of the cherub, and the face of the second the face of man, and of the third the face of a lion, and of the fourth the face of an eagle.", "dra": "And every one had four faces: one face was the face of a cherub, and the second face, the face of a man: and in the third was the face of a lion: and in the fourth the face of an eagle.", "bbe": "And every one had four faces: the first face was the face of a winged one, and the second was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "geneva": "And euery beast had foure faces: the first face was the face of a Cherub, and the second face was the face of a man, and the thirde the face of a lyon, and the fourth the face of an Egle.", "wycliffe": "Forsothe o beeste hadde foure faces; o face was the face of cherub, and the secounde face the face of a man, and in the thridde was the face of a lioun, and in the fourthe was the face of an egle;", "rotherham": "And four faces had each one,—the first face, was the face of a cherub, and, the second face, was the face of a man and the third was the face of a lion. and the fourth, was the face of an eagle.", "darby": "And every one had four faces: the first face was the face of a cherub, and the second face the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "twenty": "", "jps": "And every one had four faces: the first face was the face of the cherub, and the second face was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "acv": "And each one had four faces. The first face was the face of the cherub, and the second face was the face of a man, and the third face the face of a lion, and the fourth the face of an eagle.", "anderson": "", "haweis": "", "noyes": "And every one had four faces. The first face was the face of a cherub, and the second face was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "webster": "And every one had four faces: the first face [was] the face of a cherub, and the second face [was] the face of a man, and the third the face of a lion, and the fourth the face of an eagle.", "vulgate": "quattuor autem facies habebat unum facies una facies cherub et facies secunda facies hominis et in tertio facies leonis et in quarto facies aquilae;", "brenton": ""}}, {"v": 15, "ref": "10:15", "o": "וַ/יֵּרֹ֖מּוּ הַ/כְּרוּבִ֑ים הִ֣יא הַ/חַיָּ֔ה אֲשֶׁ֥ר רָאִ֖יתִי בִּֽ/נְהַר כְּבָֽר", "en": {"kjv": "And the cherubims were lifted up. This is the living creature that I saw by the river of Chebar.", "web": "The cherubim mounted up: this is the living creature that I saw by the river Chebar.", "bsb": "Then the cherubim rose upward. These were the living creatures I had seen by the River Kebar.", "asv": "And the cherubim mounted up: this is the living creature that I saw by the river Chebar.", "ylt": "And the cherubs are lifted up, it is the living creature that I saw by the river Chebar.", "dra": "And the cherubims were lifted up: this is the living creature that I had seen by the river Chobar.", "bbe": "And the winged ones went up on high: this is the living being which I saw by the river Chebar.", "geneva": "And the Cherubims were lifted vp: this is the beast that I sawe at the riuer Chebar.", "wycliffe": "and the cherubyns weren reisid. Thilke is the beeste, which Y hadde seyn bisidis the flood Chobar.", "rotherham": "Then arose the cherubim,—the same, was the living one, which I had seen by the river Chebar.", "darby": "And the cherubim mounted up. This was the living creature that I saw by the river Chebar.", "twenty": "", "jps": "And the cherubim mounted up--this is the living creature that I saw by the river Chebar.", "acv": "And the cherubim mounted up. This is the living creature that I saw by the river Chebar.", "anderson": "", "haweis": "", "noyes": "And the cherubs were lifted up. They were the living creatures which I saw by the river Chebar.", "webster": "And the cherubim were lifted up. This [is] the living creature that I saw by the river of Kebar.", "vulgate": "et elevata sunt cherubin ipsum est animal quod videram iuxta flumen Chobar;", "brenton": "And the cherubs were the same living creature which I saw by the river of Chobar."}}, {"v": 16, "ref": "10:16", "o": "וּ/בְ/לֶ֨כֶת֙ הַ/כְּרוּבִ֔ים יֵלְכ֥וּ הָ/אוֹפַנִּ֖ים אֶצְלָ֑/ם וּ/בִ/שְׂאֵ֨ת הַ/כְּרוּבִ֜ים אֶת כַּנְפֵי/הֶ֗ם לָ/רוּם֙ מֵ/עַ֣ל הָ/אָ֔רֶץ לֹא יִסַּ֧בּוּ הָ/אוֹפַנִּ֛ים גַּם הֵ֖ם מֵ/אֶצְלָֽ/ם", "en": {"kjv": "And when the cherubims went, the wheels went by them: and when the cherubims lifted up their wings to mount up from the earth, the same wheels also turned not from beside them.", "web": "When the cherubim went, the wheels went beside them; and when the cherubim lifted up their wings to mount up from the earth, the wheels also didn’t turn from beside them.", "bsb": "When the cherubim moved, the wheels moved beside them, and even when they spread their wings to rise from the ground, the wheels did not veer away from their side.", "asv": "And when the cherubim went, the wheels went beside them; and when the cherubim lifted up their wings to mount up from the earth, the wheels also turned not from beside them.", "ylt": "And in the going of the cherubs, the wheels go beside them; and in the cherubs lifting up their wings to be high above the earth, the wheels turn not round, even they, from being beside them.", "dra": "And when the cherubims went, the wheels also went by them: and when the cherubims lifted up their wings, to mount up from the earth, the wheels stayed not behind, but were by them.", "bbe": "And when the winged ones went, the wheels went by their side: and when their wings were lifted to take them up from the earth, the wheels were not turned from their side.", "geneva": "And when ye Cherubims went, the wheeles went by them: and when the Cherubims lift vp their wings to mount vp from the earth, the same wheeles also turned not from beside them.", "wycliffe": "And whanne cherubyns yeden, also the wheelis bisidis tho yeden to gidere; whanne cherubyns reisiden her wyngis, that tho schulden be enhaunsid fro the erthe, the wheelis abididen not stille, but also tho weren bisidis cherubyns.", "rotherham": "When the cherubim went, then went the wheels beside them,—and when the cherubim lifted up their wings, to arise from off the earth, the wheels themselves turned not from beside them;", "darby": "And when the cherubim went, the wheels went beside them; and when the cherubim lifted up their wings to mount up from the earth, the same wheels also turned not from beside them.", "twenty": "", "jps": "And when the cherubim went, the wheels went beside them; and when the cherubim lifted up their wings to mount up from the earth, the same wheels also turned not from beside them.", "acv": "And when the cherubim went, the wheels went beside them. And when the cherubim lifted up their wings to mount up from the earth, the wheels also did not turn from beside them.", "anderson": "", "haweis": "", "noyes": "And when the cherubs went, the wheels went with them; and when the cherubs lifted up their wings to mount up from the earth, the wheels turned not away from their side.", "webster": "And when the cherubim went, the wheels went by them: and when the cherubim lifted up their wings to mount up from the earth, the same wheels also turned not from beside them.", "vulgate": "cumque ambularent cherubin ibant pariter et rotae iuxta ea et cum levarent cherubin alas suas ut exaltarentur de terra non residebant rotae sed et ipsae iuxta erant;", "brenton": "And when the cherubs went, the wheels went, and they were close to them: and when the cherubs lifted up their wings to mount up from the earth, their wheels turned not."}}, {"v": 17, "ref": "10:17", "o": "בְּ/עָמְדָ֣/ם יַעֲמֹ֔דוּ וּ/בְ/רוֹמָ֖/ם יֵר֣וֹמּוּ אוֹתָ֑/ם כִּ֛י ר֥וּחַ הַ/חַיָּ֖ה בָּ/הֶֽם", "en": {"kjv": "When they stood, these stood; and when they were lifted up, these lifted up themselves also: for the spirit of the living creature was in them.", "web": "When they stood, these stood; and when they mounted up, these mounted up with them: for the spirit of the living creature was in them.", "bsb": "When the cherubim stood still, the wheels also stood still, and when they ascended, the wheels ascended with them, for the spirit of the living creatures was in the wheels.", "asv": "When they stood, these stood; and when they mounted up, these mounted up with them: for the spirit of the living creature was in them.", "ylt": "In their standing they stand, and in their exaltation they are exalted with them: for the living spirit is in them.", "dra": "When they stood, these stood: and when they were lifted up, these were lifted up: for the spirit of life was in them.", "bbe": "When they were at rest in their place, these were at rest; when they were lifted up, these went up with them: for the spirit of life was in them.", "geneva": "When the Cherubims stoode, they stood: and when they were lifted vp, they lifted the selues vp also: for the spirit of the beast was in them.", "wycliffe": "The wheelis stooden with tho cherubyns stondynge, and weren reisid with the cherubyns reisid; for the spirit of lijf was in tho wheelis.", "rotherham": "when they stood, these stood, and when they arose, these arose with them,—for, the spirit of the living one, was in them.", "darby": "When they stood, these stood; and when they mounted up, these mounted up with them: for the spirit of the living creature was in them.", "twenty": "", "jps": "When they stood, these stood, and when they mounted up, these mounted up with them; for the spirit of the living creature was in them.", "acv": "When they stood, these stood, and when they mounted up, these mounted up with them, for the spirit of the living creature was in them.", "anderson": "", "haweis": "", "noyes": "When they stood, these stood; and when they were lifted up, these were liked up with them. For the spirit of the living creatures was in them.", "webster": "When they stood, [these] stood; and when they were lifted up, [these] lifted up themselves [also]: for the spirit of the living creature [was] in them.", "vulgate": "stantibus illis stabant et cum elevatis elevabantur spiritus enim vitae erat in eis;", "brenton": "When they stood, the wheels stood; and when they mounted up, the wheels mounted up with them: because the spirit of life was in them."}}, {"v": 18, "ref": "10:18", "o": "וַ/יֵּצֵא֙ כְּב֣וֹד יְהוָ֔ה מֵ/עַ֖ל מִפְתַּ֣ן הַ/בָּ֑יִת וַֽ/יַּעֲמֹ֖ד עַל הַ/כְּרוּבִֽים", "en": {"kjv": "Then the glory of the Lord departed from off the threshold of the house, and stood over the cherubims.", "web": "Yahweh’s glory went out from over the threshold of the house, and stood over the cherubim.", "bsb": "Then the glory of the LORD moved away from the threshold of the temple and stood above the cherubim.", "asv": "And the glory of Jehovah went forth from over the threshold of the house, and stood over the cherubim.", "ylt": "And go forth doth the honour of Jehovah from off the threshold of the house, and standeth over the cherubs,", "dra": "And the glory of the Lord went forth from the threshold of the temple: and stood over the cherubims.", "bbe": "Then the glory of the Lord went out from the doorstep of the house, and came to rest over the winged ones.", "geneva": "Then the glorie of the Lord departed from aboue the doore of the house, and stoode vpon the Cherubims.", "wycliffe": "And the glorie of the Lord yede out fro the threisfold of the temple, and stood on the cherubyns.", "rotherham": "And when the glory of Yahweh went forth from off the threshold of the house,—and stood over the cherubim,", "darby": "And the glory of Jehovah departed from over the threshold of the house, and stood over the cherubim.", "twenty": "", "jps": "And the glory of HaShem went forth from off the threshold of the house, and stood over the cherubim.", "acv": "And the glory of Jehovah went forth from over the threshold of the house, and stood over the cherubim.", "anderson": "", "haweis": "", "noyes": "Then the glory of Jehovah departed from the threshold of the house, and stood over the cherubs.", "webster": "Then the glory of the LORD departed from off the threshhold of the house, and stood over the cherubim.", "vulgate": "et egressa est gloria Domini a limine templi et stetit super cherubin;", "brenton": "Then the glory of the Lord departed from the house, and went up on the cherubs."}}, {"v": 19, "ref": "10:19", "o": "וַ/יִּשְׂא֣וּ הַ/כְּרוּבִ֣ים אֶת כַּ֠נְפֵי/הֶם וַ/יֵּר֨וֹמּוּ מִן הָ/אָ֤רֶץ לְ/עֵינַ/י֙ בְּ/צֵאתָ֔/ם וְ/הָ/אֽוֹפַנִּ֖ים לְ/עֻמָּתָ֑/ם וַֽ/יַּעֲמֹ֗ד פֶּ֣תַח שַׁ֤עַר בֵּית יְהוָה֙ הַ/קַּדְמוֹנִ֔י וּ/כְב֧וֹד אֱלֹהֵֽי יִשְׂרָאֵ֛ל עֲלֵי/הֶ֖ם מִ/לְ/מָֽעְלָ/ה", "en": {"kjv": "And the cherubims lifted up their wings, and mounted up from the earth in my sight: when they went out, the wheels also were beside them, and every one stood at the door of the east gate of the Lord’s house; and the glory of the God of Israel was over them above.", "web": "The cherubim lifted up their wings, and mounted up from the earth in my sight when they went out, and the wheels beside them: and they stood at the door of the east gate of Yahweh’s house; and the glory of the God of Israel was over them above.", "bsb": "As I watched, the cherubim lifted their wings and rose up from the ground, with the wheels beside them as they went. And they stopped at the entrance of the east gate of the house of the LORD, with the glory of the God of Israel above them.", "asv": "And the cherubim lifted up their wings, and mounted up from the earth in my sight when they went forth, and the wheels beside them: and they stood at the door of the east gate of Jehovah’s house; and the glory of the God of Israel was over them above.", "ylt": "and the cherubs lift up their wings, and are lifted up from the earth before mine eyes; in their going forth, the wheels also are over-against them, and he standeth at the opening of the east gate of the house of Jehovah, and the honour of the God of Israel is over them from above.", "dra": "And the cherubims lifting up their wings, were raised from the earth before me: and as they went out, the wheels also followed: and it stood in the entry of the east gate of the house of the Lord: and the glory of the God of Israel was over them.", "bbe": "And the winged ones, lifting up their wings, went up from the earth before my eyes, with the wheels by their side: and they came to rest at the east doorway of the Lord's house; and the glory of the God of Israel was over them on high.", "geneva": "And the Cherubims lift vp their wings, and mounted vp from the earth in my sight: when they went out, the wheeles also were besides them: and euery one stoode at the entrie of the gate of the Lordes House at the East side, and the glorie of the God of Israel was vpon them on hie.", "wycliffe": "And cherubyns reisiden her wyngis, and weren enhaunsid fro the erthe bifore me; and whanne tho yeden out, also the wheelis sueden; and it stood in the entryng of the eest yate of the hous of the Lord, and the glorie of God of Israel was on tho.", "rotherham": "then the cherubim uplifted their wings and arose from the earth before mine eyes as they went forth, the wheels also in unison with them,—and it stood at the opening of the gate of the house of Yahweh that was toward the east, with the glory of the God of Israel over them, above.", "darby": "And the cherubim lifted up their wings, and mounted up from the earth in my sight, when they went out; and the wheels were beside them; and they stood at the door of the east gate of Jehovah's house; and the glory of theGod of Israel was over them above.", "twenty": "", "jps": "And the cherubim lifted up their wings, and mounted up from the earth in my sight when they went forth, and the wheels beside them; and they stood at the door of the east gate of HaShem'S house; and the glory of the G-d of Israel was over them above.", "acv": "And the cherubim lifted up their wings, and mounted up from the earth in my sight when they went forth, and the wheels beside them. And they stood at the door of the east gate of Jehovah's house, and the glory of the God of Israel was over them above.", "anderson": "", "haweis": "", "noyes": "And the cherubs lifted up their wings, and mounted up from the earth in my sight, as they went out, and the wheels were beside them. And they stood at the entrance of the east gate of the house of Jehovah, and the glory of the God of Israel was over them above.", "webster": "And the cherubim lifted up their wings, and mounted up from the earth in my sight: when they went out, the wheels also [were] beside them, and [every one] stood at the door of the east-gate of the LORD'S house; and the glory of the God of Israel [was] over them above.", "vulgate": "et elevantia cherubin alas suas exaltata sunt a terra coram me et illis egredientibus rotae quoque subsecutae sunt et stetit in introitu portae domus Domini orientalis et gloria Dei Israhel erat super ea;", "brenton": "And the cherubs lifted up their wings, and mounted up from the earth in my sight: when they went forth, the wheels were also beside them, and they stood at the entrance of the front gate of the house of the Lord; and the glory of the God of Israel was upon them above."}}, {"v": 20, "ref": "10:20", "o": "הִ֣יא הַ/חַיָּ֗ה אֲשֶׁ֥ר רָאִ֛יתִי תַּ֥חַת אֱלֹהֵֽי יִשְׂרָאֵ֖ל בִּֽ/נְהַר כְּבָ֑ר וָ/אֵדַ֕ע כִּ֥י כְרוּבִ֖ים הֵֽמָּה", "en": {"kjv": "This is the living creature that I saw under the God of Israel by the river of Chebar; and I knew that they were the cherubims.", "web": "This is the living creature that I saw under the God of Israel by the river Chebar; and I knew that they were cherubim.", "bsb": "These were the living creatures I had seen beneath the God of Israel by the River Kebar, and I knew that they were cherubim.", "asv": "This is the living creature that I saw under the God of Israel by the river Chebar; and I knew that they were cherubim.", "ylt": "It is the living creature that I saw under the God of Israel by the river Chebar, and I know that they are cherubs.", "dra": "This is the living creature, which I saw under the God of Israel by the river Chobar: and I understood that they were cherubims.", "bbe": "This is the living being which I saw under the God of Israel by the river Chebar; and it was clear to me that they were the winged ones.", "geneva": "This is the beast that I sawe vnder the God of Israel by the riuer Chebar, and I knewe that they were the Cherubims.", "wycliffe": "Thilke is the beeste, which Y siy vndur God of Israel, bisidis the flood Chobar. And Y vndurstood that foure cherubyns weren;", "rotherham": "The same, was the living one which I saw under the God of Israel by the river Chebar,- then knew I that cherubim, they were.", "darby": "This is the living creature that I saw under theGod of Israel by the river Chebar; and I knew that they were cherubim.", "twenty": "", "jps": "This is the living creature that I saw under the G-d of Israel by the river Chebar; and I knew that they were cherubim.", "acv": "This is the living creature that I saw under the God of Israel by the river Chebar, and I knew that they were cherubim.", "anderson": "", "haweis": "", "noyes": "They were the living creatures which I saw under the God of Israel by the river Chebar; and I knew that they were the cherubs.", "webster": "This [is] the living creature that I saw under the God of Israel by the river of Kebar; and I knew that they [were] the cherubim.", "vulgate": "ipsum est animal quod vidi subter Deum Israhel iuxta fluvium Chobar et intellexi quia cherubin essent;", "brenton": "This is the living creature which I saw under the God of Israel by the river of Chobar; and I knew that they were cherubs."}}, {"v": 21, "ref": "10:21", "o": "אַרְבָּעָ֨ה אַרְבָּעָ֤ה פָנִים֙ לְ/אֶחָ֔ד וְ/אַרְבַּ֥ע כְּנָפַ֖יִם לְ/אֶחָ֑ד וּ/דְמוּת֙ יְדֵ֣י אָדָ֔ם תַּ֖חַת כַּנְפֵי/הֶֽם", "en": {"kjv": "Every one had four faces apiece, and every one four wings; and the likeness of the hands of a man was under their wings.", "web": "Every one had four faces, and every one four wings; and the likeness of the hands of a man was under their wings.", "bsb": "Each had four faces and four wings, with what looked like human hands under their wings.", "asv": "Every one had four faces, and every one four wings; and the likeness of the hands of a man was under their wings.", "ylt": "Four faces are to each, and four wings to each, and the likeness of the hands of man is under their wings.", "dra": "Each one had four faces, and each one had four wings: and the likeness of a man's hand was under their wings.", "bbe": "Every one had four faces and every one had four wings; and hands like a man's hands were under their wings.", "geneva": "Euery one had foure faces, and euery one foure wings, and the likenesse of mans hands was vnder their wings.", "wycliffe": "foure faces weren to oon, and foure wyngys weren to oon; and the licnesse of the hond of a man was vndur the wyngis of tho.", "rotherham": "Four faces severally, had each one, and four wings, had each one,—and the likeness of the hands of a man, was under their wings.", "darby": "Each one had four faces, and every one four wings; and the likeness of the hands of a man was under their wings.", "twenty": "", "jps": "Every one had four faces apiece, and every one four wings; and the likeness of the hands of a man was under their wings.", "acv": "Each one had four faces, and each one four wings. And the likeness of the hands of a man was under their wings.", "anderson": "", "haweis": "", "noyes": "Every one had four faces, and every one four wings, and the form of a man’s hand was under their wings.", "webster": "Every one had four faces each, and every one four wings; and the likeness of the hands of a man [was] under their wings.", "vulgate": "quattuor per quattuor vultus uni et quattuor alae uni et similitudo manus hominis sub alis eorum;", "brenton": "Each one had four faces, and each one had eight wings; and under their wings was the likeness of men's hands."}}, {"v": 22, "ref": "10:22", "o": "וּ/דְמ֣וּת פְּנֵי/הֶ֔ם הֵ֣מָּה הַ/פָּנִ֗ים אֲשֶׁ֤ר רָאִ֨יתִי֙ עַל נְהַר כְּבָ֔ר מַרְאֵי/הֶ֖ם וְ/אוֹתָ֑/ם אִ֛ישׁ אֶל עֵ֥בֶר פָּנָ֖י/ו יֵלֵֽכוּ", "en": {"kjv": "And the likeness of their faces was the same faces which I saw by the river of Chebar, their appearances and themselves: they went every one straight forward.", "web": "As for the likeness of their faces, they were the faces which I saw by the river Chebar, their appearances and themselves; they went every one straight forward.", "bsb": "Their faces looked like the faces I had seen by the River Kebar. Each creature went straight ahead.", "asv": "And as for the likeness of their faces, they were the faces which I saw by the river Chebar, their appearances and themselves; they went every one straight forward.", "ylt": "As to the likeness of their faces, they are the faces that I saw by the river Chebar, their appearances and themselves; each straight forward they go.", "dra": "And as to the likeness of their faces, they were the same faces which I had seen by the river Chobar, and their looks, and the impulse of every one to go straight forward.", "bbe": "As for the form of their faces, they were the faces whose form I saw by the river Chebar; when they went, every one of them went straight forward.", "geneva": "And the likenesse of their faces was the selfe same faces, which I sawe by the riuer Chebar, and the appearance of the Cherubims was ye selfe same, and they went euery one straight forwarde.", "wycliffe": "And the licnesse of the cheris of tho weren thilke cheeris whiche Y hadde seyn bisidis the flood Chobar; and the biholdyng of tho, and the fersnesse of ech, was to entre bifor his face.", "rotherham": "And as for the likeness of their faces, They were the faces which I saw by the river Chebar, their appearances and themselves— every one straight before him, did they go.", "darby": "And as for the likeness of their faces, they were the faces which I had seen by the river Chebar — their appearance and themselves: they went every one straight before them.", "twenty": "", "jps": "And as for the likeness of their faces, they were the faces which I saw by the river Chebar, their appearances and themselves; they went every one straight forward.", "acv": "And as for the likeness of their faces, they were the faces which I saw by the river Chebar, their appearances and themselves. They went each one straight forward.", "anderson": "", "haweis": "", "noyes": "And as for the form of their faces, they were the faces which I saw by the river Chebar, their appearances and themselves. They went every one straight forward.", "webster": "And the likeness of their faces [was] the same faces which I saw by the river of Kebar, their appearances and themselves: they went every one straight forward.", "vulgate": "et similitudo vultuum eorum ipsi vultus quos videram iuxta fluvium Chobar et intuitus eorum et impetus singulorum ante faciem suam ingredi;", "brenton": "And as for the likeness of their faces, these are the same faces which I saw under the glory of the God of Israel by the river of Chobar: and they went each straight forward."}}]}, {"c": 11, "verses": [{"v": 1, "ref": "11:1", "o": "וַ/תִּשָּׂ֨א אֹתִ֜/י ר֗וּחַ וַ/תָּבֵ֣א אֹ֠תִ/י אֶל שַׁ֨עַר בֵּית יְהוָ֤ה הַ/קַּדְמוֹנִי֙ הַ/פּוֹנֶ֣ה קָדִ֔ימָ/ה וְ/הִנֵּה֙ בְּ/פֶ֣תַח הַ/שַּׁ֔עַר עֶשְׂרִ֥ים וַ/חֲמִשָּׁ֖ה אִ֑ישׁ וָ/אֶרְאֶ֨ה בְ/תוֹכָ֜/ם אֶת יַאֲזַנְיָ֧ה בֶן עַזֻּ֛ר וְ/אֶת פְּלַטְיָ֥הוּ בֶן בְּנָיָ֖הוּ שָׂרֵ֖י הָ/עָֽם", "en": {"kjv": "Moreover the spirit lifted me up, and brought me unto the east gate of the Lord’s house, which looketh eastward: and behold at the door of the gate five and twenty men; among whom I saw Jaazaniah the son of Azur, and Pelatiah the son of Benaiah, princes of the people.", "web": "Moreover the Spirit lifted me up, and brought me to the east gate of Yahweh’s house, which looks eastward: and see, at the door of the gate twenty-five men; and I saw in their midst Jaazaniah the son of Azzur, and Pelatiah the son of Benaiah, princes of the people.", "bsb": "Then the Spirit lifted me up and brought me to the gate of the house of the LORD that faces east. And there at the entrance of the gate were twenty-five men. Among them I saw Jaazaniah son of Azzur and Pelatiah son of Benaiah, who were leaders of the people.", "asv": "Moreover the Spirit lifted me up, and brought me unto the east gate of Jehovah’s house, which looketh eastward: and behold, at the door of the gate five and twenty men; and I saw in the midst of them Jaazaniah the son of Azzur, and Pelatiah the son of Benaiah, princes of the people.", "ylt": "And lift me up doth a spirit, and it bringeth me in unto the east gate of the house of Jehovah, that is facing the east, and lo, at the opening of the gate twenty and five men, and I see in their midst Jaazaniah son of Azzur, and Pelatiah son of Benaiah, heads of the people.", "dra": "And the spirit lifted me up, and brought me into the east gate of the house of the Lord, which looketh towards the rising of the sun: and behold in the entry of the gate five and twenty men: and I saw in the midst of them Jezonias the son of Azur, and Pheltias the son of Banaias, princes of the people.", "bbe": "And the wind, lifting me up, took me to the east doorway of the Lord's house, looking to the east: and at the door I saw twenty-five men; and among them I saw Jaazaniah, the son of Azzur, and Pelatiah, the son of Benaiah, rulers of the people.", "geneva": "Moreover, the Spirite lift me vp, and brought me vnto the East gate of the Lordes house, which lyeth Eastwarde, and beholde, at the entrie of the gate were fiue and twentie men: among whome I sawe Iaazaniah the sonne of Azur, and Pelatiah the sonne of Benaiah, the princes of the people.", "wycliffe": "And the spirit reiside me, and ledde me with ynne to the eest yate of the hous of the Lord, that biholdith the risyng of the sunne. And lo! in the entryng of the yate weren fyue and twenti men; and Y siy in the myddis of hem Jeconye, the sone of Assur, and Pheltie, the sone of Banaie, princes of the puple.", "rotherham": "And the Spirit lifted me up, and brought me into the east gate of the house of Yahweh which looketh eastward, and lo! in the opening of the gate, twenty-five men,—and I saw in their midst Jaazaniah son of Azzur and Pelatiah son of Benaiah princes of the people.", "darby": "And the Spirit lifted me up, and brought me unto the east gate of Jehovah's house, which looketh eastward; and behold, at the door of the gate were five and twenty men; and I saw in the midst of them Jaazaniah the son of Azzur, and Pelatiah the son of Benaiah, princes of the people.", "twenty": "", "jps": "Then a spirit lifted me up, and brought me unto the east gate of HaShem'S house, which looketh eastward; and behold at the door of the gate five and twenty men; and I saw in the midst of them Jaazaniah the son of Azzur, and Pelatiah the son of Benaiah, princes of the people.", "acv": "Moreover the Spirit lifted me up, and brought me to the east gate of Jehovah's house, which looks eastward. And, behold, at the door of the gate twenty-five men. And I saw in the midst of them Jaazaniah the son of Azzur, and Pelatiah the son of Benaiah, rulers of the people.", "anderson": "", "haweis": "", "noyes": "Then the spirit lifted me up, and brought me to the east gate of the house of Jehovah, that looketh toward the east; and behold, at the entrance of the gate were five and twenty men; among whom I saw Jaazaniah, the son of Azur, and Pelatiah, the son of Benaiah, princes of the people.", "webster": "Moreover the spirit lifted me up, and brought me to the east-gate of the LORD'S house, which looketh eastward: and behold, at the door of the gate five and twenty men; among whom I saw Jaazaniah the son of Azur, and Pelatiah the son of Benaiah, princes of the people.", "vulgate": "et elevavit me spiritus et introduxit me ad portam domus Domini orientalem quae respicit solis ortum et ecce in introitu portae viginti quinque viri et vidi in medio eorum Hiezoniam filium Azur et Pheltiam filium Banaiae principes populi;", "brenton": "Moreover the Spirit took me up, and brought me to the front gate of the house of the Lord, that looks eastward: and behold at the entrance of the gate were about five and twenty men; and I saw in the midst of them Jechonias the son of Ezer, and Phaltias the son of Banaeas, the leaders of the people."}}, {"v": 2, "ref": "11:2", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י בֶּן אָדָ֕ם אֵ֣לֶּה הָ/אֲנָשִׁ֞ים הַ/חֹשְׁבִ֥ים אָ֛וֶן וְ/הַ/יֹּעֲצִ֥ים עֲצַת רָ֖ע בָּ/עִ֥יר הַ/זֹּֽאת", "en": {"kjv": "Then said he unto me, Son of man, these are the men that devise mischief, and give wicked counsel in this city:", "web": "He said to me, Son of man, these are the men who devise iniquity, and who give wicked counsel in this city;", "bsb": "And the LORD said to me, “Son of man, these are the men who plot evil and give wicked counsel in this city.", "asv": "And he said unto me, Son of man, these are the men that devise iniquity, and that give wicked counsel in this city;", "ylt": "And He saith unto me, `Son of man, these are the men who are devising iniquity, and who are giving evil counsel in this city;", "dra": "And he said to me: Son of man, these are the men that study iniquity, and frame a wicked counsel in this city,", "bbe": "Then he said to me, Son of man, these are the men who are designing evil, who are teaching evil ways in this town:", "geneva": "Then said he vnto me, Sonne of man, these are the men that imagine mischiefe, and deuise wicked counsell in this citie.", "wycliffe": "And he seide to me, Thou, sone of man, these ben the men that thenken wickidnesse, and treten the worste counsel in this citee,", "rotherham": "Then said he unto me, Son of man, These, are the men who are devising iniquity, and who are counselling wicked counsel in this city;", "darby": "And he said unto me, Son of man, these are the men that devise iniquity, and give wicked counsel in this city:", "twenty": "", "jps": "And He said unto me: 'Son of man, these are the men that devise iniquity, and that give wicked counsel in this city;", "acv": "And he said to me, Son of man, these are the men who devise iniquity, and who give wicked counsel in this city,", "anderson": "", "haweis": "", "noyes": "Then said He to me: These are the men that devise mischief, and form evil designs in this city;", "webster": "Then said he to me, Son of man, these [are] the men that devise mischief, and give wicked counsel in this city:", "vulgate": "dixitque ad me fili hominis hii viri qui cogitant iniquitatem et tractant consilium pessimum in urbe ista;", "brenton": "And the Lord said to me, Son of man, these are the men that devise vanities, and take evil counsel in this city:"}}, {"v": 3, "ref": "11:3", "o": "הָ/אֹ֣מְרִ֔ים לֹ֥א בְ/קָר֖וֹב בְּנ֣וֹת בָּתִּ֑ים הִ֣יא הַ/סִּ֔יר וַ/אֲנַ֖חְנוּ הַ/בָּשָֽׂר", "en": {"kjv": "Which say, It is not near; let us build houses: this city is the caldron, and we be the flesh.", "web": "who say, The time is not near to build houses: this is the cauldron, and we are the meat.", "bsb": "They are saying, ‘Is not the time near to build houses? The city is the cooking pot, and we are the meat.’", "asv": "that say, The time is not near to build houses: this city is the caldron, and we are the flesh.", "ylt": "who are saying, It is not near--to build houses, it is the pot, and we the flesh.", "dra": "Saying: Were not houses lately built? This city is the caldron, and we the flesh.", "bbe": "Who say, This is not the time for building houses: this town is the cooking-pot and we are the flesh.", "geneva": "For they say, It is not neere, let vs builde houses: this citie is the caldron, and wee be the flesh.", "wycliffe": "and seien, Whether housis weren not bildid a while ago? this is the cawdrun, forsothe we ben fleischis.", "rotherham": "who are saying, Not near! let us build houses,— It, is the caldron, and, we, are the flesh!", "darby": "who say, It is not the time to build houses: this is the cauldron, and we are the flesh.", "twenty": "", "jps": "that say: The time is not near to build houses! this city is the caldron, and we are the flesh.", "acv": "who say, The time is not near to build houses. This city is the caldron, and we are the flesh.", "anderson": "", "haweis": "", "noyes": "who say, \"The time is not near that we should build houses. This city is the caldron, and we are the flesh.\"", "webster": "Who say, [It is] not near; let us build houses: this [city is] the caldron, and we [are] the flesh.", "vulgate": "dicentes nonne dudum aedificatae sunt domus haec est lebes nos autem carnes;", "brenton": "who say, Have not the houses been newly built? This is the caldron, and we are the flesh."}}, {"v": 4, "ref": "11:4", "o": "לָ/כֵ֖ן הִנָּבֵ֣א עֲלֵי/הֶ֑ם הִנָּבֵ֖א בֶּן אָדָֽם", "en": {"kjv": "Therefore prophesy against them, prophesy, O son of man.", "web": "Therefore prophesy against them, prophesy, son of man.", "bsb": "Therefore prophesy against them; prophesy, O son of man!”", "asv": "Therefore prophesy against them, prophesy, O son of man.", "ylt": "Therefore prophesy concerning them, prophesy, son of man.'", "dra": "Therefore prophesy against them, prophesy, thou son of man.", "bbe": "For this cause be a prophet against them, be a prophet, O son of man.", "geneva": "Therefore prophesie against them, sonne of man, prophesie.", "wycliffe": "Therfor profesie thou of hem, profesie thou, sone of man.", "rotherham": "Therefore, prophesy against them, —prophesy. Son of man.", "darby": "Therefore prophesy against them, prophesy, son of man.", "twenty": "", "jps": "Therefore prophesy against them, prophesy, O son of man.'", "acv": "Therefore prophesy against them. Prophesy, O son of man.", "anderson": "", "haweis": "", "noyes": "Therefore, prophesy against them, prophesy, O son of man!", "webster": "Therefore prophesy against them, prophesy, O son of man.", "vulgate": "idcirco vaticinare de eis vaticinare fili hominis;", "brenton": "Therefore prophesy against them, prophesy, son of man."}}, {"v": 5, "ref": "11:5", "o": "וַ/תִּפֹּ֣ל עָלַ/י֮ ר֣וּחַ יְהוָה֒ וַ/יֹּ֣אמֶר אֵלַ֗/י אֱמֹר֙ כֹּה אָמַ֣ר יְהוָ֔ה כֵּ֥ן אֲמַרְתֶּ֖ם בֵּ֣ית יִשְׂרָאֵ֑ל וּ/מַעֲל֥וֹת רֽוּחֲ/כֶ֖ם אֲנִ֥י יְדַעְתִּֽי/הָ", "en": {"kjv": "And the Spirit of the Lord fell upon me, and said unto me, Speak; Thus saith the Lord; Thus have ye said, O house of Israel: for I know the things that come into your mind, every one of them.", "web": "The Spirit of Yahweh fell on me, and he said to me, Speak, Thus says Yahweh: Thus you have said, house of Israel; for I know the things that come into your mind.", "bsb": "And the Spirit of the LORD fell upon me and told me to declare that this is what the LORD says: “That is what you are thinking, O house of Israel; and I know the thoughts that arise in your minds.", "asv": "And the Spirit of Jehovah fell upon me, and he said unto me, Speak, Thus saith Jehovah: Thus have ye said, O house of Israel; for I know the things that come into your mind.", "ylt": "And fall upon me doth the Spirit of Jehovah, and He saith unto me, `Say: Thus said Jehovah: Rightly ye have said, O house of Israel, And the steps of your spirit I have known.", "dra": "And the spirit of the Lord fell upon me, and said to me: Speak: Thus saith the Lord: Thus have you spoken, O house of Israel, for I know the thoughts of your heart.", "bbe": "And the spirit of the Lord came on me, and he said to me, Say, These are the words of the Lord: This is what you have said, O children of Israel; what comes into your mind is clear to me.", "geneva": "And the Spirite of the Lord fell vpon me, and said vnto me, Speake, Thus saith the Lord, O ye house of Israel, this haue ye said, and I know that which riseth vp of your mindes.", "wycliffe": "And the Spirit of the Lord felle in to me, and seide to me, Speke thou, The Lord seith these thingis, Ye hous of Israel spaken thus, and Y knewe the thouytis of youre herte;", "rotherham": "Then fell upon me the Spirit of Yahweh, and he said unto me Say—Thus, saith Yahweh, Thus have ye said O house of Israel, Yea, the things that come up on your spirit, I, know every one.", "darby": "And the Spirit of Jehovah fell on me, and said unto me, Speak, Thus saith Jehovah: Thus have ye said, O house of Israel; and the things that come into your mind, I know them.", "twenty": "", "jps": "And the spirit of HaShem fell upon me, and He said unto me: 'Speak: Thus saith HaShem: Thus have ye said, O house of Israel; for I know the things that come into your mind.", "acv": "And the Spirit of Jehovah fell upon me, and he said to me, Speak, Thus says Jehovah: Thus ye have said, O house of Israel, for I know the things that come into your mind.", "anderson": "", "haweis": "", "noyes": "And the spirit of Jehovah fell upon me, and he said to me, Speak: Thus saith Jehovah: Thus have ye said, O house of Israel! For I know the things that come into your mind, every one of them.", "webster": "And the spirit of the LORD fell upon me, and said to me, Speak; Thus saith the LORD; Thus have ye said, O house of Israel: for I know the things that come into your mind, [every one of] them.", "vulgate": "et inruit in me spiritus Domini et dixit ad me loquere haec dicit Dominus sic locuti estis domus Israhel et cogitationes cordis vestri ego novi;", "brenton": "And the Spirit of the Lord fell upon me, and said to me, say; Thus saith the Lord; Thus have ye said, O house of Israel: and I know the devices of your spirit."}}, {"v": 6, "ref": "11:6", "o": "הִרְבֵּיתֶ֥ם חַלְלֵי/כֶ֖ם בָּ/עִ֣יר הַ/זֹּ֑את וּ/מִלֵּאתֶ֥ם חוּצֹתֶ֖י/הָ חָלָֽל", "en": {"kjv": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "web": "You have multiplied your slain in this city, and you have filled its streets with the slain.", "bsb": "You have multiplied those you killed in this city and filled its streets with the dead.", "asv": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "ylt": "Ye multiplied your wounded in this city, And filled its out-places with the wounded.", "dra": "You have killed a great many in this city, and you have filled the streets thereof with the slain.", "bbe": "You have made great the number of your dead in this town, you have made its streets full of dead men.", "geneva": "Many haue ye murthered in this citie, and ye haue filled the streets thereof with the slaine.", "wycliffe": "ye killiden ful many men in this citee, and ye filliden the weies therof with slayn men.", "rotherham": "Ye have multiplied your slain in this city,- And have filled her streets with slain.", "darby": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "twenty": "", "jps": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "acv": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "anderson": "", "haweis": "", "noyes": "Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.", "webster": "Ye have multiplied your slain in this city, and ye have filled its streets with the slain.", "vulgate": "plurimos occidistis in urbe hac et implestis vias eius interfectis;", "brenton": "Ye have multiplied your dead in this city, and ye have filled your ways with slain men."}}, {"v": 7, "ref": "11:7", "o": "לָ/כֵ֗ן כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ חַלְלֵי/כֶם֙ אֲשֶׁ֣ר שַׂמְתֶּ֣ם בְּ/תוֹכָ֔/הּ הֵ֥מָּה הַ/בָּשָׂ֖ר וְ/הִ֣יא הַ/סִּ֑יר וְ/אֶתְ/כֶ֖ם הוֹצִ֥יא מִ/תּוֹכָֽ/הּ", "en": {"kjv": "Therefore thus saith the Lord God; Your slain whom ye have laid in the midst of it, they are the flesh, and this city is the caldron: but I will bring you forth out of the midst of it.", "web": "Therefore thus says the Lord Yahweh: Your slain whom you have laid in its midst, they are the meat, and this is the cauldron; but you shall be brought out of its midst.", "bsb": "Therefore this is what the Lord GOD says: The slain you have laid within this city are the meat, and the city is the pot; but I will remove you from it.", "asv": "Therefore thus saith the Lord Jehovah: Your slain whom ye have laid in the midst of it, they are the flesh, and this city is the caldron; but ye shall be brought forth out of the midst of it.", "ylt": "Therefore, thus said the Lord Jehovah: Your wounded whom ye placed in its midst, They are the flesh, and it is the pot, And you he hath brought out from its midst.", "dra": "Therefore thus saith the Lord God: Your slain, whom you have laid in the midst thereof, they are the flesh, all this is the caldron: and I will bring you forth out of the midst thereof.", "bbe": "For this reason the Lord has said: Your dead whom you have put down in its streets, they are the flesh, and this town is the cooking-pot: but I will make you come out from inside it.", "geneva": "Therefore thus saith the Lord God, They that ye haue slaine, and haue layed in the middes of it, they are the flesh, and this citie is the caldron, but I wil bring you foorth of the mids of it.", "wycliffe": "Therfor the Lord seith these thingis, Youre slayn men, whiche ye puttiden in the myddis therof, these ben fleischis, and this is the cawdrun; and Y schal lede you out of the myddis therof.", "rotherham": "Therefore Thus, saith My Lord Yahweh, Your slain. whom ye have laid in her midst, They are the flesh, and She is the caldron,—when ye are taken out of her midst.", "darby": "Therefore thus saith the Lord Jehovah: Your slain whom ye have laid in the midst of it, they are the flesh, and it is the cauldron; but you will I bring forth out of the midst of it.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Your slain whom ye have laid in the midst of it, they are the flesh, and this city is the caldron; but ye shall be brought forth out of the midst of it.", "acv": "Therefore thus says the lord Jehovah: Your slain whom ye have laid in the midst of it, they are the flesh, and this city is the caldron, but ye shall be brought forth out of the midst of it.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Your slain, whom ye have laid in the midst of it, they are the flesh, and this city is the caldron; but you will I bring forth out of the midst of it.", "webster": "Therefore thus saith the Lord GOD; Your slain whom ye have laid in the midst of it, they [are] the flesh, and this [city is] the caldron: but I will bring you forth out of the midst of it.", "vulgate": "propterea haec dicit Dominus Deus interfecti vestri quos posuistis in medio eius hii sunt carnes et haec est lebes et educam vos de medio eius;", "brenton": "Therefore thus saith the Lord; Your dead whom ye have smitten in the midst of it, these are the flesh, and thiscity is the caldron: but I will bring you forth out of the midst of it."}}, {"v": 8, "ref": "11:8", "o": "חֶ֖רֶב יְרֵאתֶ֑ם וְ/חֶ֨רֶב֙ אָבִ֣יא עֲלֵי/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Ye have feared the sword; and I will bring a sword upon you, saith the Lord God.", "web": "You have feared the sword; and I will bring the sword on you, says the Lord Yahweh.", "bsb": "You fear the sword, so I will bring the sword against you, declares the Lord GOD.", "asv": "Ye have feared the sword; and I will bring the sword upon you, saith the Lord Jehovah.", "ylt": "A sword ye have feared, And a sword I bring in against you, An affirmation of the Lord Jehovah.", "dra": "You have feared the sword, and I will bring the sword upon you, saith the Lord God.", "bbe": "You have been fearing the sword, and I will send the sword on you, says the Lord.", "geneva": "Ye haue feared the sworde, and I wil bring a sworde vpon you, saith the Lord God.", "wycliffe": "Ye dredden swerd, and Y schal brynge in swerd on you, seith the Lord God.", "rotherham": "A sword, have ye feared,— And a sword, will I bring in upon you, Declareth My Lord Yahweh.", "darby": "Ye have feared the sword, and I will bring a sword upon you, saith the Lord Jehovah.", "twenty": "", "jps": "Ye have feared the sword; and the sword will I bring upon you, saith the L-rd GOD.", "acv": "Ye have feared the sword, and I will bring the sword upon you, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Ye have feared the sword, and the sword will I bring upon you, saith the Lord Jehovah.", "webster": "Ye have feared the sword; and I will bring a sword upon you, saith the Lord GOD.", "vulgate": "gladium metuistis et gladium inducam super vos ait Dominus Deus;", "brenton": "Ye fear the sword; and I will bring a sword upon you, saith the Lord."}}, {"v": 9, "ref": "11:9", "o": "וְ/הוֹצֵאתִ֤י אֶתְ/כֶם֙ מִ/תּוֹכָ֔/הּ וְ/נָתַתִּ֥י אֶתְ/כֶ֖ם בְּ/יַד זָרִ֑ים וְ/עָשִׂ֛יתִי בָ/כֶ֖ם שְׁפָטִֽים", "en": {"kjv": "And I will bring you out of the midst thereof, and deliver you into the hands of strangers, and will execute judgments among you.", "web": "I will bring you out of its midst, and deliver you into the hands of strangers, and will execute judgments among you.", "bsb": "I will bring you out of the city and deliver you into the hands of foreigners, and I will execute judgments against you.", "asv": "And I will bring you forth out of the midst thereof, and deliver you into the hands of strangers, and will execute judgments among you.", "ylt": "And I have brought you out of its midst, And given you into the hand of strangers, And I have done among you judgments.", "dra": "And I will cast you out of the midst thereof, and I will deliver you into the hand of the enemies, and I will execute judgments upon you.", "bbe": "I will make you come out from inside the town and will give you up into the hands of men from other lands, and will be judge among you.", "geneva": "And I will bring you out of the middes thereof, and deliuer you into the hands of strangers, and will execute iudgements among you.", "wycliffe": "And Y schal caste you out of the myddis therof, and Y schal yyue you in to the hond of enemyes, and Y schal make domes in you.", "rotherham": "So will I take you forth out of her midst, and will deliver you into the hand of foreigners, —and will execute upon you judgments.", "darby": "And I will bring you out of the midst of it, and give you into the hands of strangers, and will execute judgments among you.", "twenty": "", "jps": "And I will bring you forth out of the midst thereof, and deliver you into the hands of strangers, and will execute judgments among you.", "acv": "And I will bring you forth out of the midst of it, and deliver you into the hands of strangers, and will execute judgments among you.", "anderson": "", "haweis": "", "noyes": "And I will bring you out of the midst thereof, and deliver you into the hands of strangers, and execute judgments upon you.", "webster": "And I will bring you out of the midst of it, and deliver you into the hands of strangers, and will execute judgments among you.", "vulgate": "et eiciam vos de medio eius daboque vos in manu hostium et faciam in vobis iudicia;", "brenton": "And I will bring you forth out of the midst of it, and will deliver you into the hands of strangers, and will execute judgments among you."}}, {"v": 10, "ref": "11:10", "o": "בַּ/חֶ֣רֶב תִּפֹּ֔לוּ עַל גְּב֥וּל יִשְׂרָאֵ֖ל אֶשְׁפּ֣וֹט אֶתְ/כֶ֑ם וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Ye shall fall by the sword; I will judge you in the border of Israel; and ye shall know that I am the Lord.", "web": "You shall fall by the sword; I will judge you in the border of Israel; and you shall know that I am Yahweh.", "bsb": "You will fall by the sword, and I will judge you even to the borders of Israel. Then you will know that I am the LORD.", "asv": "Ye shall fall by the sword; I will judge you in the border of Israel; and ye shall know that I am Jehovah.", "ylt": "By the sword ye do fall, On the border of Israel I do judge you, And ye have known that I am Jehovah.", "dra": "You shall fall by the sword: I will judge you in the borders of Israel, and you shall know that I am the Lord.", "bbe": "You will come to your death by the sword; and I will be your judge in the land of Israel; and you will be certain that I am the Lord.", "geneva": "Ye shall fall by the sworde, and I wil iudge you in the border of Israel, and ye shall knowe that I am the Lord.", "wycliffe": "Bi swerd ye schulen falle doun, Y schal deme you in the endis of Israel; and ye schulen wite, that Y am the Lord.", "rotherham": "By the sword, shall ye fall, Upon the boundary of Israel, will I judge you, —So shall ye know that, I, am Yahweh.", "darby": "Ye shall fall by the sword; I will judge you in the borders of Israel; and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "Ye shall fall by the sword: I will judge you upon the border of Israel; and ye shall know that I am HaShem.", "acv": "Ye shall fall by the sword. I will judge you in the border of Israel, and ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "Ye shall fall by the sword; on the borders of Israel will I judge you, that ye may know that I am Jehovah.", "webster": "Ye shall fall by the sword; I will judge you in the border of Israel; and ye shall know that I [am] the LORD.", "vulgate": "gladio cadetis in finibus Israhel iudicabo vos et scietis quia ego Dominus;", "brenton": "Ye shall fall by the sword; I will judge you on the mountains of Israel; and ye shall know that I am the Lord."}}, {"v": 11, "ref": "11:11", "o": "הִ֗יא לֹֽא תִהְיֶ֤ה לָ/כֶם֙ לְ/סִ֔יר וְ/אַתֶּ֛ם תִּהְי֥וּ בְ/תוֹכָ֖/הּ לְ/בָשָׂ֑ר אֶל גְּב֥וּל יִשְׂרָאֵ֖ל אֶשְׁפֹּ֥ט אֶתְ/כֶֽם", "en": {"kjv": "This city shall not be your caldron, neither shall ye be the flesh in the midst thereof; but I will judge you in the border of Israel:", "web": "This shall not be your cauldron, neither shall you be the meat in its midst; I will judge you in the border of Israel;", "bsb": "The city will not be a pot for you, nor will you be the meat within it. I will judge you even to the borders of Israel.", "asv": "This city shall not be your caldron, neither shall ye be the flesh in the midst thereof; I will judge you in the border of Israel;", "ylt": "It is not to you for a pot, Nor are ye in its midst for flesh, At the border of Israel I do judge you.", "dra": "This shall not be as a caldron to you, and you shall not be as flesh in the midst thereof: I will judge you in the borders of Israel.", "bbe": "This town will not be your cooking-pot, and you will not be the flesh inside it; I will be your judge at the limit of the land of Israel;", "geneva": "This citie shall not be your caldron, neyther shall ye be the flesh in the middes thereof, but I will iudge you in the border of Israel.", "wycliffe": "This schal not be to you in to a cawdrun, and ye schulen not be in to fleischis in the myddis therof; Y schal deme you in the endis of Israel,", "rotherham": "This city shall not serve you for a caldron, Neither shall, ye, serve in the midst thereof for flesh,—Near the boundary of Israel, will I judge you,", "darby": "This shall not be your cauldron, neither shall ye be the flesh in the midst of it: I will judge you in the borders of Israel;", "twenty": "", "jps": "Though this city shall not be your caldron, ye shall be the flesh in the midst thereof; I will judge you upon the border of Israel;", "acv": "This city shall not be your caldron, nor shall ye be the flesh in the midst thereof. I will judge you in the border of Israel,", "anderson": "", "haweis": "", "noyes": "This city shall not be your caldron, neither shall ye be the flesh in the midst thereof. On the borders of Israel will I judge you,", "webster": "This [city] shall not be your caldron, neither shall ye be the flesh in the midst of it; [but] I will judge you in the border of Israel:", "vulgate": "haec non erit vobis in lebetem et vos non eritis in medio eius in carnes in finibus Israhel iudicabo vos;", "brenton": "And it came to pass, while I was prophesying, that Phaltias the son of Banaeas died. And I fell upon my face, and cried with a loud voice, and said, Alas, alas, O Lord! wilt thou utterly destroy the remnant of Israel?"}}, {"v": 12, "ref": "11:12", "o": "וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה אֲשֶׁ֤ר בְּ/חֻקַּ/י֙ לֹ֣א הֲלַכְתֶּ֔ם וּ/מִשְׁפָּטַ֖/י לֹ֣א עֲשִׂיתֶ֑ם וּֽ/כְ/מִשְׁפְּטֵ֧י הַ/גּוֹיִ֛ם אֲשֶׁ֥ר סְבִיבוֹתֵי/כֶ֖ם עֲשִׂיתֶֽם", "en": {"kjv": "And ye shall know that I am the Lord: for ye have not walked in my statutes, neither executed my judgments, but have done after the manners of the heathen that are round about you.", "web": "and you shall know that I am Yahweh: for you have not walked in my statutes, neither have you executed my ordinances, but have done after the ordinances of the nations that are around you.", "bsb": "Then you will know that I am the LORD. For you have neither followed My statutes nor practiced My ordinances, but you have conformed to the ordinances of the nations around you.”", "asv": "and ye shall know that I am Jehovah: for ye have not walked in my statutes, neither have ye executed mine ordinances, but have done after the ordinances of the nations that are round about you.", "ylt": "And ye have known that I am Jehovah, For in My statutes ye have not walked, And My Judgments ye have not done, And according to the judgments of the nations Who are round about you--ye have done!'", "dra": "And you shall know that I am the Lord: because you have not walked in my commandments, and have not done my judgments, but you have done according to the judgments of the nations that are round about you.", "bbe": "And you will be certain that I am the Lord: for you have not been guided by my rules or given effect to my orders, but you have been living by the orders of the nations round about you.", "geneva": "And ye shall knowe that I am the Lord: for ye haue not walked in my statutes, neither executed my iudgements, but haue done after the maners of the heathen, that are round about you.", "wycliffe": "and ye schulen wite, that Y am the Lord. For ye yeden not in myn heestis, and ye dyden not my domes, but ye wrouyten bi the domes of hethene men, that ben in youre cumpas.", "rotherham": "So shall ye know that, I, am Yahweh. In whose statutes, ye have not walked And whose appointments, ye have not executed,— But according to the appointments of the nations that are round about you, have ye done.", "darby": "and ye shall know that I [am] Jehovah, in whose statutes ye have not walked, neither have done mine ordinances, but have done after the ordinances of the nations that are round about you.", "twenty": "", "jps": "and ye shall know that I am HaShem; for ye have not walked in My statutes, neither have ye executed Mine ordinances, but have done after the ordinances of the nations that are round about you.'", "acv": "and ye shall know that I am Jehovah. For ye have not walked in my statutes, nor have ye executed my ordinances, but have done according to the ordinances of the nations that are round about you.", "anderson": "", "haweis": "", "noyes": "that ye may know that I am Jehovah, in whose statutes ye have not walked, and whose ordinances ye have not observed, but have done according to the manners of the nations, that are round about you.", "webster": "And ye shall know that I [am] the LORD: for ye have not walked in my statutes, neither executed my judgments, but have done after the manners of the heathen that [are] around you.", "vulgate": "et scietis quia ego Dominus qui in praeceptis meis non ambulastis et iudicia mea non fecistis sed iuxta iudicia gentium quae in circuitu vestro sunt estis operati;", "brenton": ""}}, {"v": 13, "ref": "11:13", "o": "וַֽ/יְהִי֙ כְּ/הִנָּ֣בְאִ֔/י וּ/פְלַטְיָ֥הוּ בֶן בְּנָיָ֖ה מֵ֑ת וָ/אֶפֹּ֨ל עַל פָּנַ֜/י וָ/אֶזְעַ֣ק קוֹל גָּד֗וֹל וָ/אֹמַר֙ אֲהָהּ֙ אֲדֹנָ֣/י יְהוִ֔ה כָּלָה֙ אַתָּ֣ה עֹשֶׂ֔ה אֵ֖ת שְׁאֵרִ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then fell I down upon my face, and cried with a loud voice, and said, Ah Lord God! wilt thou make a full end of the remnant of Israel?", "web": "When I prophesied, Pelatiah the son of Benaiah died. Then fell I down on my face, and cried with a loud voice, and said, “Ah Lord Yahweh! will you make a full end of the remnant of Israel?”", "bsb": "Now as I was prophesying, Pelatiah son of Benaiah died. Then I fell facedown and cried out in a loud voice, “Oh, Lord GOD, will You bring the remnant of Israel to a complete end?”", "asv": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then fell I down upon my face, and cried with a loud voice, and said, Ah Lord Jehovah! wilt thou make a full end of the remnant of Israel?", "ylt": "And it cometh to pass, at my prophesying, that Pelatiah son of Benaiah is dying, and I fall on my face, and cry--a loud voice--and say, `Ah, Lord Jehovah, an end Thou art making of the remnant of Israel.'", "dra": "And it came to pass, when I prophesied, that Pheltias the son of Banaias died: and I fell down upon my face, and I cried with a loud voice: and said: Alas, alas, alas, O Lord God: wilt thou make an end of all the remnant of Israel?", "bbe": "Now while I was saying these things, death came to Pelatiah, the son of Benaiah. Then falling down on my face and crying out with a loud voice, I said, Ah, Lord! will you put an end to all the rest of Israel?", "geneva": "And when I prophesied, Pelatiah the sonne of Benaiah dyed: then fell I downe vpon my face, and cryed with a loude voyce, and saide, Ah Lord God, wilt thou then vtterly destroy all the remnant of Israel?", "wycliffe": "And it was doon, whanne Y profesiede, Pheltie, the sone of Banaie, was deed; and Y felle doun on my face, and Y criede with greet vois, and seide, Alas! alas! alas! Lord God, thou makist endyng of the remenauntis of Israel.", "rotherham": "And it came to pass as I prophesied, that Pelatiah son of Benaiah died,—so then I fell down upon my face and made outcry with a loud voice and said— Alas! My Lord Yahweh! A full end, art thou making of the remnant of Israel?", "darby": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. And I fell down on my face, and cried with a loud voice, and said, Ah, Lord Jehovah! wilt thou make a full end of the remnant of Israel?", "twenty": "", "jps": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then fell I down upon my face, and cried with a loud voice, and said: 'Ah L-rd GOD! wilt Thou make a full end of the remnant of Israel?'", "acv": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then I fell down upon my face, and cried with a loud voice, and said, Ah lord Jehovah! Will thou make a full end of the remnant of Israel?", "anderson": "", "haweis": "", "noyes": "And it came to pass, when I prophesied, that Pelatiah, the son of Benaiah, died. Then I fell down on my face, and cried with a loud voice, and said, Ah, Lord Jehovah, wilt thou make a full end of the remnant of Israel?", "webster": "And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then I fell down upon my face, and cried with a loud voice, and said, Ah Lord GOD! wilt thou make a full end of the remnant of Israel?", "vulgate": "et factum est cum prophetarem Pheltias filius Banaiae mortuus est et cecidi in faciem meam clamans voce magna et dixi heu heu heu Domine Deus consummationem tu facis reliquiarum Israhel;", "brenton": ""}}, {"v": 14, "ref": "11:14", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Again the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Againe the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 15, "ref": "11:15", "o": "בֶּן אָדָ֗ם אַחֶ֤י/ךָ אַחֶ֨י/ךָ֙ אַנְשֵׁ֣י גְאֻלָּתֶ֔/ךָ וְ/כָל בֵּ֥ית יִשְׂרָאֵ֖ל כֻּלֹּ֑/ה אֲשֶׁר֩ אָמְר֨וּ לָ/הֶ֜ם יֹשְׁבֵ֣י יְרוּשָׁלִַ֗ם רַֽחֲקוּ֙ מֵ/עַ֣ל יְהוָ֔ה לָ֥/נוּ הִ֛יא נִתְּנָ֥ה הָ/אָ֖רֶץ לְ/מוֹרָשָֽׁה", "en": {"kjv": "Son of man, thy brethren, even thy brethren, the men of thy kindred, and all the house of Israel wholly, are they unto whom the inhabitants of Jerusalem have said, Get you far from the Lord: unto us is this land given in possession.", "web": "“Son of man, your brothers, even your brothers, the men of your relatives, and all the house of Israel, all of them, to whom the inhabitants of Jerusalem have said, ‘Go far away from Yahweh. This land has been given to us for a possession.’”", "bsb": "“Son of man, your brothers—your relatives, your fellow exiles, and the whole house of Israel—are those of whom the people of Jerusalem have said, ‘They are far away from the LORD; this land has been given to us as a possession.’", "asv": "Son of man, thy brethren, even thy brethren, the men of thy kindred, and all the house of Israel, all of them, are they unto whom the inhabitants of Jerusalem have said, Get you far from Jehovah; unto us is this land given for a possession.", "ylt": "`Son of man, thy brethren, thy brethren, men of thy kindred, and all the house of Israel--all of it, are they to whom inhabitants of Jerusalem have said, Keep far off from Jehovah;", "dra": "Son of man, thy brethren, thy brethren, thy kinsmen, and all the house of Israel, all they to whom the inhabitants of Jerusalem have said: Get ye far from the Lord, the land is given in possession to us.", "bbe": "Son of man, your countrymen, your relations, and all the children of Israel, all of them, are those to whom the people of Jerusalem have said, Go far from the Lord; this land is given to us for a heritage:", "geneva": "Sonne of man, thy brethren, euen thy brethren, the men of thy kindred, and all the house of Israel, wholy are they vnto whome the inhabitants of Ierusalem haue said, Depart ye farre from the Lord: for the lande is giuen vs in possession.", "wycliffe": "and he seide, Sone of man, thi britheren, thi kynes men, and al the hous of Israel, and alle men, to whiche the dwelleris of Jerusalem seiden, Go ye awei fer fro the Lord, the lond is youun to vs in to possessioun.", "rotherham": "Son of man Thine own brethren, thine own brethren the men of thy kindred, even all the house of Israel all of it are they to whom the inhabitants of Jerusalem have said, Get you far away from Yahweh, To us, it is that the land, hath been given, for a possession!", "darby": "Son of man, [it is] thy brethren, thy brethren, the men of thy kindred, and all the house of Israel, the whole of it, unto whom the inhabitants of Jerusalem say, Get you far from Jehovah: unto us is this land given for a possession.", "twenty": "", "jps": "'Son of man, as for thy brethren, even thy brethren, the men of thy kindred, and all the house of Israel, all of them, concerning whom the inhabitants of Jerusalem have said: Get you far from HaShem! unto us is this land given for a possession;", "acv": "Son of man, thy brothers, even thy brothers, the men of thy kindred, and all the house of Israel, all of them, are those to whom the inhabitants of Jerusalem have said, Get you far from Jehovah. This land is given to us for a possession.", "anderson": "", "haweis": "", "noyes": "Son of man, thy brethren, even thy brethren, the men of thy near kindred, and the whole house of Israel, are they to whom the inhabitants of Jerusalem say, \"Remove ye far from Jehovah; to us is the land given in possession!\"", "webster": "Son of man, thy brethren, [even] thy brethren, the men of thy kindred, and all the house of Israel wholly, [are] they to whom the inhabitants of Jerusalem have said, Retire far from the LORD: to us is this land given in possession.", "vulgate": "fili hominis fratres tui fratres tui viri propinqui tui et omnis domus Israhel universi quibus dixerunt habitatores Hierusalem longe recedite a Domino nobis data est terra in possessionem;", "brenton": "Son of man, thy brethren, and the men of thy captivity, and all the house of Israel are come to the full, to whom the inhabitants of Jerusalem said, Keep ye far away from the Lord: the land is given to us for an inheritance."}}, {"v": 16, "ref": "11:16", "o": "לָ/כֵ֣ן אֱמֹ֗ר כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ כִּ֤י הִרְחַקְתִּי/ם֙ בַּ/גּוֹיִ֔ם וְ/כִ֥י הֲפִֽיצוֹתִ֖י/ם בָּ/אֲרָצ֑וֹת וָ/אֱהִ֤י לָ/הֶם֙ לְ/מִקְדָּ֣שׁ מְעַ֔ט בָּ/אֲרָצ֖וֹת אֲשֶׁר בָּ֥אוּ שָֽׁם", "en": {"kjv": "Therefore say, Thus saith the Lord God; Although I have cast them far off among the heathen, and although I have scattered them among the countries, yet will I be to them as a little sanctuary in the countries where they shall come.", "web": "Therefore say, Thus says the Lord Yahweh: Whereas I have removed them far off among the nations, and whereas I have scattered them among the countries, yet will I be to them a sanctuary for a little while in the countries where they have come.", "bsb": "Therefore declare that this is what the Lord GOD says: ‘Although I sent them far away among the nations and scattered them among the countries, yet for a little while I have been a sanctuary for them in the countries to which they have gone.’", "asv": "Therefore say, Thus saith the Lord Jehovah: Whereas I have removed them far off among the nations, and whereas I have scattered them among the countries, yet will I be to them a sanctuary for a little while in the countries where they are come.", "ylt": "it is ours, the land hath been given for an inheritance; therefore say: Thus said the Lord Jehovah: Because I put them afar off among nations, And because I scattered them through lands, I also am to them for a little sanctuary, In lands whither they have gone in.", "dra": "Therefore thus saith the Lord God: Because I have removed them far off among the Gentiles, and because I have scattered them among the countries: I will be to them a little sanctuary in the countries whither they are come.", "bbe": "For this reason say, This is what the Lord has said: Though I have had them moved far off among the nations, and though I have sent them wandering among the countries, still I have been a safe place for them for a little time in the countries where they have come.", "geneva": "Therefore say, Thus saith the Lord God, Although I haue cast them farre off among the heathen, and although I haue scattered them among the countreis, yet wil I be to them as a litle Sanctuarie in ye countreis where they shall come.", "wycliffe": "Therfor the Lord God seith these thingis, For Y made hem fer among hethene men, and for Y scateride hem in londis, Y schal be to hem in to a litil halewyng, in the londis to whiche thei camen.", "rotherham": "Therefore, say, Thus saith My Lord. Yahweh, Although I have removed them far away among the nations, And although I have dispersed them throughout the lands Yet have I become to them a sanctuary for a little while, in the lands which they have entered", "darby": "Therefore say, Thus saith the Lord Jehovah: Although I have removed them far off among the nations, and although I have scattered them among the countries, yet will I be to them as a little sanctuary in the countries whither they are come.", "twenty": "", "jps": "therefore say: Thus saith the L-rd GOD: Although I have removed them far off among the nations, and although I have scattered them among the countries, yet have I been to them as a little sanctuary in the countries where they are come;", "acv": "Therefore say, Thus says the lord Jehovah: Whereas I have removed them far off among the nations, and whereas I have scattered them among the countries, yet I will be to them a sanctuary for a little while in the countries where they have come.", "anderson": "", "haweis": "", "noyes": "Therefore say, Thus saith the Lord Jehovah: Though I have cast them far off among the nations, and scattered them among the countries, yet I will be to them as a sanctuary for a short time in the countries whither they are come.", "webster": "Therefore say, Thus saith the Lord GOD; Although I have cast them far off among the heathen, and although I have scattered them among the countries, yet will I be to them as a little sanctuary in the countries where they shall come.", "vulgate": "propterea haec dicit Dominus Deus quia longe feci eos in gentibus et quia dispersi eos in terris ero eis in sanctificationem modicam in terris ad quas venerunt;", "brenton": "Therefore say thou, Thus saith the Lord; I will cast them off among the nations, and will disperse them into every land, yet will I be to them for a little sanctuary in the countries which they shall enter."}}, {"v": 17, "ref": "11:17", "o": "לָ/כֵ֣ן אֱמֹ֗ר כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ וְ/קִבַּצְתִּ֤י אֶתְ/כֶם֙ מִן הָ֣/עַמִּ֔ים וְ/אָסַפְתִּ֣י אֶתְ/כֶ֔ם מִן הָ֣/אֲרָצ֔וֹת אֲשֶׁ֥ר נְפֹצוֹתֶ֖ם בָּ/הֶ֑ם וְ/נָתַתִּ֥י לָ/כֶ֖ם אֶת אַדְמַ֥ת יִשְׂרָאֵֽל", "en": {"kjv": "Therefore say, Thus saith the Lord God; I will even gather you from the people, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.", "web": "Therefore say, Thus says the Lord Yahweh: I will gather you from the peoples, and assemble you out of the countries where you have been scattered, and I will give you the land of Israel.", "bsb": "Therefore declare that this is what the Lord GOD says: ‘I will gather you from the peoples and assemble you from the countries to which you have been scattered, and I will give back to you the land of Israel.’", "asv": "Therefore say, Thus saith the Lord Jehovah: I will gather you from the peoples, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.", "ylt": "Therefore say: Thus said the Lord Jehovah: And I have assembled you from the peoples, And I have gathered you from the lands, Into which ye have been scattered, And I have given to you the ground of Israel.", "dra": "Therefore speak to them: Thus saith the Lord God: I will gather you from among the peoples, and assemble you out of the countries wherein you are scattered, and I will give you the land of Israel.", "bbe": "Then say, This is what the Lord has said: I will get you together from the peoples, and make you come out of the countries where you have been sent in flight, and I will give you the land of Israel.", "geneva": "Therefore say, Thus saith the Lord God, I will gather you againe from the people, and assemble you out of the countreis where ye haue bene scattered, and I will giue you ye land of Israel.", "wycliffe": "Therfor speke thou, The Lord God seith these thingis, Y schal gadere you fro puplis, and Y schal gadere you togidere fro londis, in whiche ye ben scatered; and Y schal yyue the erthe of Israel to you.", "rotherham": "Therefore say, Thus saith My Lord Yahweh, Therefore will I assemble you from among the peoples, And gather you out of the lands wherein ye have been dispersed,- And will give you the soil of Israel.", "darby": "Therefore say, Thus saith the Lord Jehovah: I will even gather you from the peoples, and assemble you out of the countries where ye are scattered, and I will give you the land of Israel.", "twenty": "", "jps": "therefore say: Thus saith the L-rd GOD: I will even gather you from the peoples, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.", "acv": "Therefore say, Thus says the lord Jehovah. I will gather you from the peoples, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.", "anderson": "", "haweis": "", "noyes": "Therefore say, Thus saith the Lord Jehovah: I will gather you from the nations, and assemble you from the countries where ye have been scattered, and I will give you the land of Israel.", "webster": "Therefore say, Thus saith the Lord GOD; I will even gather you from the people, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.", "vulgate": "propterea loquere haec dicit Dominus Deus congregabo vos de populis et adunabo de terris in quibus dispersi estis daboque vobis humum Israhel;", "brenton": "Therefore say thou, Thus saith the Lord; I will also take them from the heathen, and gather them out of the lands wherein I have scattered them, and will give them the land of Israel."}}, {"v": 18, "ref": "11:18", "o": "וּ/בָ֖אוּ שָׁ֑מָּ/ה וְ/הֵסִ֜ירוּ אֶת כָּל שִׁקּוּצֶ֛י/הָ וְ/אֶת כָּל תּוֹעֲבוֹתֶ֖י/הָ מִמֶּֽ/נָּה", "en": {"kjv": "And they shall come thither, and they shall take away all the detestable things thereof and all the abominations thereof from thence.", "web": "They shall come there, and they shall take away all the detestable things of it and all its abominations from there.", "bsb": "When they return to it, they will remove all its detestable things and all its abominations.", "asv": "And they shall come thither, and they shall take away all the detestable things thereof and all the abominations thereof from thence.", "ylt": "And they have gone in thither. And turned aside all its detestable things, And all its abominations--out of it.", "dra": "And they shall go in thither, and shall take away all the scandals, and all the abominations thereof from thence.", "bbe": "And they will come there, and take away all the hated and disgusting things from it.", "geneva": "And they shall come thither, and they shall take away all the idoles thereof, and all the abominations thereof from thence.", "wycliffe": "And thei schulen entre thidur, and schulen do awei alle offenciouns, and alle abhomynaciouns therof in that dai.", "rotherham": "So shall they come in thither,— and take away all her detestable things, and all her abominations, out of her;", "darby": "And they shall come thither, and they shall take away from thence all its detestable things and all its abominations.", "twenty": "", "jps": "And they shall come thither, and they shall take away all the detestable things thereof and all the abominations thereof from thence.", "acv": "And they shall come there, and they shall take away from there all the detestable things of it and all the abominations of it.", "anderson": "", "haweis": "", "noyes": "And they shall come thither, and they shall take away from thence all the detestable things thereof, and all the abominations thereof.", "webster": "And they shall come thither, and they shall take away from thence all its detestable things, and all its abominations.", "vulgate": "et ingredientur illuc et auferent omnes offensiones cunctasque abominationes eius de illa;", "brenton": "And they shall enter in there, and shall remove all the abominations of it, and all its iniquities from it."}}, {"v": 19, "ref": "11:19", "o": "וְ/נָתַתִּ֤י לָ/הֶם֙ לֵ֣ב אֶחָ֔ד וְ/ר֥וּחַ חֲדָשָׁ֖ה אֶתֵּ֣ן בְּ/קִרְבְּ/כֶ֑ם וַ/הֲסִ֨רֹתִ֜י לֵ֤ב הָ/אֶ֨בֶן֙ מִ/בְּשָׂרָ֔/ם וְ/נָתַתִּ֥י לָ/הֶ֖ם לֵ֥ב בָּשָֽׂר", "en": {"kjv": "And I will give them one heart, and I will put a new spirit within you; and I will take the stony heart out of their flesh, and will give them an heart of flesh:", "web": "I will give them one heart, and I will put a new spirit within you; and I will take the stony heart out of their flesh, and will give them a heart of flesh;", "bsb": "And I will give them singleness of heart and put a new spirit within them; I will remove their heart of stone and give them a heart of flesh,", "asv": "And I will give them one heart, and I will put a new spirit within you; and I will take the stony heart out of their flesh, and will give them a heart of flesh;", "ylt": "And I have given to them one heart, And a new spirit I do give in your midst, And I have turned the heart of stone out of their flesh, And I have given to them a heart of flesh.", "dra": "And I will give them one heart, and will put a new spirit in their bowels: and I will take away the stony heart out of their flesh, and will give them a heart of flesh:", "bbe": "And I will give them a new heart, and I will put a new spirit in them; and I will take the heart of stone out of their flesh and give them a heart of flesh:", "geneva": "And I will giue them one heart, and I will put a newe spirit within their bowels: and I will take the stonie heart out of their bodies, and will giue them an heart of flesh,", "wycliffe": "And Y schal yyue to hem oon herte, and Y schal yyue a newe spirit in the entrails of hem; and Y schal take awei a stony herte fro the fleisch of hem, and Y schal yyue to hem an herte of fleisch;", "rotherham": "And I will give them another heart, And a new spirit, will I put within you,—And will take away the heart of stone out of their flesh, and give them a heart of flesh:", "darby": "And I will give them one heart, and I will put a new spirit within you; and I will take away the stony heart out of their flesh, and will give them a heart of flesh;", "twenty": "", "jps": "And I will give them one heart, and I will put a new spirit within you; and I will remove the stony heart out of their flesh, and will give them a heart of flesh;", "acv": "And I will give them one heart, and I will put a new spirit within you. And I will take the stony heart out of their flesh, and will give them a heart of flesh,", "anderson": "", "haweis": "", "noyes": "And I will give them one heart, and I will put a new spirit within them; and I will take out of them the heart of stone, and will give them a heart of flesh,", "webster": "And I will give them one heart, and I will put a new spirit within you; and I will take the stony heart out of their flesh, and will give them a heart of flesh:", "vulgate": "et dabo eis cor unum et spiritum novum tribuam in visceribus eorum et auferam cor lapideum de carne eorum et dabo eis cor carneum;", "brenton": "And I will give them another heart, and will put a new spirit within them; and will extract the heart of stone from their flesh, and give them a heart of flesh:"}}, {"v": 20, "ref": "11:20", "o": "לְמַ֨עַן֙ בְּ/חֻקֹּתַ֣/י יֵלֵ֔כוּ וְ/אֶת מִשְׁפָּטַ֥/י יִשְׁמְר֖וּ וְ/עָשׂ֣וּ אֹתָ֑/ם וְ/הָיוּ לִ֣/י לְ/עָ֔ם וַ/אֲנִ֕י אֶהְיֶ֥ה לָ/הֶ֖ם לֵ/אלֹהִֽים", "en": {"kjv": "That they may walk in my statutes, and keep mine ordinances, and do them: and they shall be my people, and I will be their God.", "web": "that they may walk in my statutes, and keep my ordinances, and do them: and they shall be my people, and I will be their God.", "bsb": "so that they may follow My statutes, keep My ordinances, and practice them. Then they will be My people, and I will be their God.", "asv": "that they may walk in my statutes, and keep mine ordinances, and do them: and they shall be my people, and I will be their God.", "ylt": "So that in My statutes they walk, And My judgments they keep, and have done them, And they have been to me for a people, And I am to them for God.", "dra": "That they may walk in my commandments, and keep my judgments, and do them: and that they may be my people, and I may be their God.", "bbe": "So that they may be guided by my rules and keep my orders and do them: and they will be to me a people, and I will be to them a God.", "geneva": "That they may walke in my statutes, and keepe my iudgements, and execute them: and they shall be my people, and I will be their God.", "wycliffe": "that thei go in my comaundementis, and kepe my domes, and do tho; and that thei be in to a puple to me, and Y be in to God to hem.", "rotherham": "To the end that in my statutes, they may walk, And mine appointments, they may keep, and do them,— So shall they become my people, And I will become their God.", "darby": "that they may walk in my statutes, and keep mine ordinances, and do them; and they shall be my people, and I will be theirGod.", "twenty": "", "jps": "that they may walk in My statutes, and keep Mine ordinances, and do them; and they shall be My people, and I will be their G-d.", "acv": "that they may walk in my statutes, and keep my ordinances, and do them. And they shall be my people, and I will be their God.", "anderson": "", "haweis": "", "noyes": "that they may walk in my statutes, and observe my ordinances, and keep them; and they shall be my people, and I will be their God.", "webster": "That they may walk in my statutes, and keep my ordinances, and do them: and they shall be my people, and I will be their God.", "vulgate": "ut in praeceptis meis ambulent et iudicia mea custodiant faciantque ea et sint mihi in populum et ego sim eis in Deum;", "brenton": "that they may walk in my commandments, and keep mine ordinances, and do them: and they shall be to me a people, and I will be to them a God."}}, {"v": 21, "ref": "11:21", "o": "וְ/אֶל לֵ֧ב שִׁקּוּצֵי/הֶ֛ם וְ/תוֹעֲבוֹתֵי/הֶ֖ם לִבָּ֣/ם הֹלֵ֑ךְ דַּרְכָּ/ם֙ בְּ/רֹאשָׁ֣/ם נָתַ֔תִּי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "But as for them whose heart walketh after the heart of their detestable things and their abominations, I will recompense their way upon their own heads, saith the Lord God.", "web": "But as for them whose heart walks after the heart of their detestable things and their abominations, I will bring their way on their own heads, says the Lord Yahweh.", "bsb": "But as for those whose hearts pursue detestable things and abominations, I will bring their conduct down upon their own heads, declares the Lord GOD.”", "asv": "But as for them whose heart walketh after the heart of their detestable things and their abominations, I will bring their way upon their own heads, saith the Lord Jehovah.", "ylt": "As to those whose heart is going unto the heart Of their detestable and their abominable things, Their way on their head I have put, An affirmation of the Lord Jehovah.'", "dra": "But as for them whose heart walketh after their scandals and abominations, I will lay their way upon their head, saith the Lord God.", "bbe": "But as for those whose heart goes after their hated and disgusting things, I will send on their heads the punishment of their ways, says the Lord.", "geneva": "But vpon them, whose heart is towarde their idoles, and whose affection goeth after their abominations, I will lay their way vpon their owne heades, saith the Lord God.", "wycliffe": "But of whiche the herte goith after her offendyngis and abhomynaciouns, Y schal sette the weie of hem in her heed, seith the Lord God.", "rotherham": "But as for them who having a heart for their detestable things and for their abominations after their own heart, do walk, Their way upon their own heads, will I render, Declareth My Lord Yahweh.", "darby": "But as for them whose heart walketh well-pleased with their detestable things and their abominations, I will recompense their way upon their heads, saith the Lord Jehovah.", "twenty": "", "jps": "But as for them whose heart walketh after the heart of their detestable things and their abominations, I will bring their way upon their own heads, saith the L-rd GOD.'", "acv": "But as for those whose heart walks according to the heart of their detestable things and their abominations, I will bring their way upon their own heads, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "But as for them whose heart walketh according to the pleasure of their detestable things and their abominations, I will recompense their way upon their heads, saith the Lord Jehovah.", "webster": "But [as for them] whose heart walketh after the heart of their detestable things and their abominations, I will recompense their way upon their own heads, saith the Lord GOD.", "vulgate": "quorum cor post offendicula et abominationes suas ambulat horum viam in capite suo ponam dicit Dominus Deus;", "brenton": "And as for the heart set upon their abominations and their iniquities, as their heart went after them, I have recompensed their ways on their heads, saith the Lord."}}, {"v": 22, "ref": "11:22", "o": "וַ/יִּשְׂא֤וּ הַ/כְּרוּבִים֙ אֶת כַּנְפֵי/הֶ֔ם וְ/הָ/אֽוֹפַנִּ֖ים לְ/עֻמָּתָ֑/ם וּ/כְב֧וֹד אֱלֹהֵֽי יִשְׂרָאֵ֛ל עֲלֵי/הֶ֖ם מִ/לְ/מָֽעְלָ/ה", "en": {"kjv": "Then did the cherubims lift up their wings, and the wheels beside them; and the glory of the God of Israel was over them above.", "web": "Then the cherubim lifted up their wings, and the wheels were beside them; and the glory of the God of Israel was over them above.", "bsb": "Then the cherubim, with the wheels beside them, spread their wings, and the glory of the God of Israel was above them.", "asv": "Then did the cherubim lift up their wings, and the wheels were beside them; and the glory of the God of Israel was over them above.", "ylt": "And the cherubs lift up their wings, and the wheels are over-against them, and the honour of the God of Israel is over them above.", "dra": "And the cherubims lifted up their wings, and the wheels with them: and the glory of the God of Israel was over them.", "bbe": "Then the wings of the winged ones were lifted up, and the wheels were by their side; and the glory of the God of Israel was over them on high.", "geneva": "Then did the Cherubims lift vp their wings, and the wheeles besides them, and the glorie of the God of Israel was vpon them on hie.", "wycliffe": "And the cherubyns reisiden her wyngis, and the wheelis yeden with tho, and the glorie of God of Israel was on tho.", "rotherham": "Then did the cherubim lift up their wings, the wheels also going in unison with them,— the glory of the God of Israel, being over them above.", "darby": "And the cherubim lifted up their wings, and the wheels were beside them; and the glory of theGod of Israel was over them above.", "twenty": "", "jps": "Then did the cherubim lift up their wings, and the wheels were beside them; and the glory of the G-d of Israel was over them above.", "acv": "Then the cherubim lifted up their wings, and the wheels were beside them, and the glory of the God of Israel was over them above.", "anderson": "", "haweis": "", "noyes": "Then did the cherubs lift up their wings, and the wheels were beside them; and the glory of the God of Israel was over them above.", "webster": "Then the cherubim raised their wings, and the wheels beside them; and the glory of the God of Israel [was] over them above.", "vulgate": "et elevaverunt cherubin alas suas et rotae cum eis et gloria Dei Israhel erat super ea;", "brenton": "Then the cherubs lifted up their wings, and the wheels beside them; and the glory of the God of Israel was over them above."}}, {"v": 23, "ref": "11:23", "o": "וַ/יַּ֨עַל֙ כְּב֣וֹד יְהוָ֔ה מֵ/עַ֖ל תּ֣וֹךְ הָ/עִ֑יר וַֽ/יַּעֲמֹד֙ עַל הָ/הָ֔ר אֲשֶׁ֖ר מִ/קֶּ֥דֶם לָ/עִֽיר", "en": {"kjv": "And the glory of the Lord went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "web": "Yahweh’s glory went up from the midst of the city, and stood on the mountain which is on the east side of the city.", "bsb": "And the glory of the LORD rose up from within the city and stood over the mountain east of the city.", "asv": "And the glory of Jehovah went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "ylt": "And the honour of Jehovah goeth up from off the midst of the city, and standeth on the mountain, that is on the east of the city.", "dra": "And the glory of the Lord went up from the midst of the city, and stood over the mount that is on the east side of the city.", "bbe": "And the glory of the Lord went up from inside the town, and came to rest on the mountain on the east side of the town.", "geneva": "And the glorie of the Lord went vp from the middes of the citie, and stoode vpon the moutaine which is towarde the East side of the citie.", "wycliffe": "And the glorie of the Lord stiede fro the myddis of the citee, and stood on the hil, which is at the eest of the citee.", "rotherham": "Thus went up the glory of Yahweh, out from the midst of the city,—and stood on the mountain, which is on the east of the city.", "darby": "And the glory of Jehovah went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "twenty": "", "jps": "And the glory of HaShem went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "acv": "And the glory of Jehovah went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "anderson": "", "haweis": "", "noyes": "And the glory of Jehovah went up from the midst of the city, and stood upon the mountain which is on the east side of the city.", "webster": "And the glory of the LORD went up from the midst of the city, and stood upon the mountain which [is] on the east side of the city.", "vulgate": "et ascendit gloria Domini de medio civitatis stetitque super montem qui est ad orientem urbis;", "brenton": "And the glory of the Lord went up from the midst of the city, and stood on the mountain which was in front of the city."}}, {"v": 24, "ref": "11:24", "o": "וְ/ר֣וּחַ נְשָׂאַ֗תְ/נִי וַ/תְּבִיאֵ֤/נִי כַשְׂדִּ֨ימָ/ה֙ אֶל הַ/גּוֹלָ֔ה בַּ/מַּרְאֶ֖ה בְּ/ר֣וּחַ אֱלֹהִ֑ים וַ/יַּ֨עַל֙ מֵֽ/עָלַ֔/י הַ/מַּרְאֶ֖ה אֲשֶׁ֥ר רָאִֽיתִי", "en": {"kjv": "Afterwards the spirit took me up, and brought me in a vision by the Spirit of God into Chaldea, to them of the captivity. So the vision that I had seen went up from me.", "web": "The Spirit lifted me up, and brought me in the vision by the Spirit of God into Chaldea, to them of the captivity. So the vision that I had seen went up from me.", "bsb": "And the Spirit lifted me up and carried me back to Chaldea, to the exiles in the vision given by the Spirit of God. After the vision had gone up from me,", "asv": "And the Spirit lifted me up, and brought me in the vision by the Spirit of God into Chaldea, to them of the captivity. So the vision that I had seen went up from me.", "ylt": "And a spirit hath lifted me up, and bringeth me in to Chaldea, unto the Removed, in a vision, by the Spirit of God, and go up from off me doth the vision that I have seen;", "dra": "And the spirit lifted me up, and brought me into Chaldea, to them of the captivity, in vision, by the spirit of God: and the vision which I had seen was taken up from me.", "bbe": "And the wind, lifting me up, took me in the visions of God into Chaldaea, to those who had been taken away as prisoners. So the vision which I had seen went away from me.", "geneva": "Afterwarde the Spirite tooke me vp, and brought me in a vision by the Spirit of God into Caldea to them that were led away captiues: so the vision that I had seene, went vp from me.", "wycliffe": "And the spirit reiside me, and brouyte me in to Caldee, to the passyng ouer, in visioun bi the spirit of God; and the visioun which Y hadde seyn, was takun awei fro me.", "rotherham": "And, the spirit lifted me up, and brought me to Chaldea unto them of the captivity, in the vision by the Spirit of God,—thus went up from me, the vision which I had seen.", "darby": "And the Spirit lifted me up, and brought me in the vision by the Spirit ofGod into Chaldea, to them of the captivity; and the vision that I had seen went up from me.", "twenty": "", "jps": "And a spirit lifted me up, and brought me in the vision by the spirit of G-d into Chaldea, to them of the captivity. So the vision that I had seen went up from Me.", "acv": "And the Spirit lifted me up, and brought me in the vision by the Spirit of God into Chaldea, to those of the captivity. So the vision that I had seen went up from me.", "anderson": "", "haweis": "", "noyes": "Then the spirit took me up, and brought me to Chaldaea, to them of the captivity, in vision, by the spirit of God. And the vision which I had seen went up from me.", "webster": "Afterwards the spirit took me up, and brought me in vision by the Spirit of God into Chaldea, to them of the captivity. So the vision that I had seen went up from me.", "vulgate": "et spiritus levavit me adduxitque in Chaldeam ad transmigrationem in visione in spiritu Dei et sublata est a me visio quam videram;", "brenton": "And the Spirit took me up, and brought me to the land of the Chaldeans, to the captivity, in a vision by the Spirit of God: and I went up after the vision which I saw."}}, {"v": 25, "ref": "11:25", "o": "וָ/אֲדַבֵּ֖ר אֶל הַ/גּוֹלָ֑ה אֵ֛ת כָּל דִּבְרֵ֥י יְהוָ֖ה אֲשֶׁ֥ר הֶרְאָֽ/נִי", "en": {"kjv": "Then I spake unto them of the captivity all the things that the Lord had shewed me.", "web": "Then I spoke to them of the captivity all the things that Yahweh had shown me.", "bsb": "I told the exiles everything the LORD had shown me.", "asv": "Then I spake unto them of the captivity all the things that Jehovah had showed me.", "ylt": "and I speak unto the Removed all the matters of Jehovah that He hath shewed me.", "dra": "And I spoke to them of the captivity all the words of the Lord, which he had shewn me.", "bbe": "Then I gave an account to those who had been taken prisoners of all the things which the Lord had made me see.", "geneva": "Then I declared vnto them that were led away captiues, all the things that the Lord had shewed me.", "wycliffe": "And Y spak to the passyng ouer alle the wordis of the Lord, whiche he hadde schewid to me.", "rotherham": "So I spake unto them of the captivity,—all the words of Yahweh which he had shewed me.", "darby": "And I spoke unto them of the captivity all the things that Jehovah had shewn me.", "twenty": "", "jps": "Then I spoke unto them of the captivity all the things that HaShem had shown me.", "acv": "Then I spoke to those of the captivity all the things that Jehovah had shown me.", "anderson": "", "haweis": "", "noyes": "Then I spake to them of the captivity all the words of Jehovah which he had showed me.", "webster": "Then I spoke to them of the captivity all the things that the LORD had shown me.", "vulgate": "et locutus sum ad transmigrationem omnia verba Domini quae ostenderat mihi;", "brenton": "And I spoke to the captivity all the words of the Lord which he had shewed me."}}]}, {"c": 12, "verses": [{"v": 1, "ref": "12:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord also came unto me, saying,", "web": "Yahweh’s word also came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "The word of Jehovah also came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "The worde of the Lord also came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "The word of HaShem also came unto me, saying:", "acv": "The word of Jehovah also came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "The word of the LORD also came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "12:2", "o": "בֶּן אָדָ֕ם בְּ/ת֥וֹךְ בֵּית הַ/מֶּ֖רִי אַתָּ֣ה יֹשֵׁ֑ב אֲשֶׁ֣ר עֵינַיִם֩ לָ/הֶ֨ם לִ/רְא֜וֹת וְ/לֹ֣א רָא֗וּ אָזְנַ֨יִם לָ/הֶ֤ם לִ/שְׁמֹ֨עַ֙ וְ/לֹ֣א שָׁמֵ֔עוּ כִּ֛י בֵּ֥ית מְרִ֖י הֵֽם", "en": {"kjv": "Son of man, thou dwellest in the midst of a rebellious house, which have eyes to see, and see not; they have ears to hear, and hear not: for they are a rebellious house.", "web": "Son of man, you dwell in the midst of the rebellious house, who have eyes to see, and don’t see, who have ears to hear, and don’t hear; for they are a rebellious house.", "bsb": "“Son of man, you are living in a rebellious house. They have eyes to see but do not see, and ears to hear but do not hear, for they are a rebellious house.", "asv": "Son of man, thou dwellest in the midst of the rebellious house, that have eyes to see, and see not, that have ears to hear, and hear not; for they are a rebellious house.", "ylt": "`Son of man, in the midst of the rebellious house thou art dwelling, that have eyes to see, and they have not seen; ears they have to hear, and they have not heard; for a rebellious house are they.", "dra": "Son of man, thou dwellest in the midst of a provoking house: who have eyes to see, and see not: and ears to hear, and hear not: for they are a provoking house.", "bbe": "Son of man, you are living among an uncontrolled people, who have eyes to see but see not, and ears for hearing but they do not give ear; for they are an uncontrolled people.", "geneva": "Sonne of man, thou dwellest in the middes of a rebellious house, which haue eyes to see, and see not: they haue eares to heare, and heare not: for they are a rebellious house.", "wycliffe": "and he seide, Sone of man, thou dwellist in the myddis of an hous terrynge to wraththe, which han iyen to se, and seen not, and eeris to here, and heren not; for it is an hous terrynge to wraththe.", "rotherham": "Son of man. In the midst of a perverse house, dost thou dwell,— Who have eyes to see—and have not seen. Ears have they to hear—and have no heard, For a perverse house, they are.", "darby": "Son of man, thou dwellest in the midst of a rebellious house, which have eyes to see, and see not, which have ears to hear, and hear not; for they are a rebellious house.", "twenty": "", "jps": "'Son of man, thou dwellest in the midst of the rebellious house, that have eyes to see, and see not, that have ears to hear, and hear not; for they are a rebellious house.", "acv": "Son of man, thou dwell in the midst of the rebellious house, that have eyes to see, and see not, that have ears to hear, and hear not, for they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "Son of man, thou dwellest in the midst of a rebellious house; they have eyes to see, and see not; they have ears to hear, and hear not; for they are a rebellious house.", "webster": "Son of man, thou dwellest in the midst of a rebellious house, who have eyes to see, and see not; they have ears to hear, and hear not: for they [are] a rebellious house.", "vulgate": "fili hominis in medio domus exasperantis tu habitas qui oculos habent ad videndum et non vident et aures ad audiendum et non audiunt quia domus exasperans est;", "brenton": "Son of man, thou dwellest in the midst of the iniquities of those, who have eyes to see, and see not; and have ears to hear, and hear not: because it is a provoking house."}}, {"v": 3, "ref": "12:3", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם עֲשֵׂ֤ה לְ/ךָ֙ כְּלֵ֣י גוֹלָ֔ה וּ/גְלֵ֥ה יוֹמָ֖ם לְ/עֵֽינֵי/הֶ֑ם וְ/גָלִ֨יתָ מִ/מְּקוֹמְ/ךָ֜ אֶל מָק֤וֹם אַחֵר֙ לְ/עֵ֣ינֵי/הֶ֔ם אוּלַ֣י יִרְא֔וּ כִּ֛י בֵּ֥ית מְרִ֖י הֵֽמָּה", "en": {"kjv": "Therefore, thou son of man, prepare thee stuff for removing, and remove by day in their sight; and thou shalt remove from thy place to another place in their sight: it may be they will consider, though they be a rebellious house.", "web": "Therefore, you son of man, prepare your stuff for moving, and move by day in their sight; and you shall move from your place to another place in their sight: it may be they will consider, though they are a rebellious house.", "bsb": "Therefore, son of man, pack your bags for exile. In broad daylight, set out from your place and go to another as they watch. Perhaps they will understand, though they are a rebellious house.", "asv": "Therefore, thou son of man, prepare thee stuff for removing, and remove by day in their sight; and thou shalt remove from thy place to another place in their sight: it may be they will consider, though they are a rebellious house.", "ylt": "And thou, son of man, make to thee vessels of removal, and remove by day before their eyes, and thou hast removed from thy place unto another place before their eyes, it may be they consider, for a rebellious house they are .", "dra": "Thou, therefore, O son of man, prepare thee all necessaries for removing, and remove by day into their sight: and thou shalt remove out of thy place to another place in their sight, if so be they will regard it: for they are a provoking house.", "bbe": "And you, O son of man, by day, before their eyes, get ready the vessels of one who is taken away, and go away from your place to another place before their eyes: it may be that they will see, though they are an uncontrolled people.", "geneva": "Therefore thou sonne of man, prepare thy stuffe to goe into captiuitie, and goe foorth by day in their sight: and thou shalt passe from thy place to another place in their sight, if it be possible that they may consider it: for they are a rebellious house.", "wycliffe": "Therfor thou, sone of man, make to thee vessels of passing ouer, and thou schalt passe ouer bi dai bifor hem; forsothe thou schalt passe ouer fro thi place to another place, in the siyt of hem, if perauenture thei biholden, for it is an hous terrynge to wraththe.", "rotherham": "Thou, therefore Son of man, Prepare thee baggage for exile, and exile thyself, by day, before their eyes,—so shalt thou exile thyself out of thy place unto another place before their eyes, peradventure they will consider— though a perverse house, they are.", "darby": "And thou, son of man, prepare thee a captive's baggage, and go captive by day in their sight; and thou shalt go captive from thy place to another place in their sight. It may be they will consider, though they are a rebellious house.", "twenty": "", "jps": "Therefore, thou son of man, prepare thee stuff for exile, and remove as though for exile by day in their sight; and thou shalt remove from thy place to another place in their sight; it may be they will perceive, for they are a rebellious house.", "acv": "Therefore, thou son of man, prepare thee stuff for moving, and move by day in their sight. And thou shall move from thy place to another place in their sight. It may be they will consider, though they are a rebellious house.", "anderson": "", "haweis": "", "noyes": "Therefore, thou son of man, prepare thee stuff for removing from the land; and remove by day in their sight, and remove from thy place to another place before their eyes. It may be they will consider, though they be a rebellious house.", "webster": "Therefore, thou son of man, prepare thee stuff for removing, and remove by day in their sight; and thou shalt remove from thy place to another place in their sight; it may be they will consider, though they [are] a rebellious house.", "vulgate": "tu ergo fili hominis fac tibi vasa transmigrationis et transmigrabis per diem coram eis transmigrabis autem de loco tuo ad locum alterum in conspectu eorum si forte aspiciant quia domus exasperans est;", "brenton": "Thou therefore, son of man, prepare thyself baggage for going into captivity by day in their sight; and thou shalt be led into captivity from thy place into another place in their sight; that they may see that it is a provoking house."}}, {"v": 4, "ref": "12:4", "o": "וְ/הוֹצֵאתָ֨ כֵלֶ֜י/ךָ כִּ/כְלֵ֥י גוֹלָ֛ה יוֹמָ֖ם לְ/עֵֽינֵי/הֶ֑ם וְ/אַתָּ֗ה תֵּצֵ֤א בָ/עֶ֨רֶב֙ לְ/עֵ֣ינֵי/הֶ֔ם כְּ/מוֹצָאֵ֖י גּוֹלָֽה", "en": {"kjv": "Then shalt thou bring forth thy stuff by day in their sight, as stuff for removing: and thou shalt go forth at even in their sight, as they that go forth into captivity.", "web": "You shall bring out your stuff by day in their sight, as stuff for moving; and you shall go out yourself at even in their sight, as when men go out into exile.", "bsb": "Bring out your baggage for exile by day, as they watch. Then in the evening, as they watch, go out like those who go into exile.", "asv": "And thou shalt bring forth thy stuff by day in their sight, as stuff for removing; and thou shalt go forth thyself at even in their sight, as when men go forth into exile.", "ylt": "And thou hast brought forth thy vessels as vessels of removal by day before their eyes, and thou, thou dost go forth at even before their eyes, as the goings forth of a removal.", "dra": "And thou shalt bring forth thy furniture as the furniture of one that is removing by day in their sight: and thou shalt go forth in the evening in their presence, as one goeth forth that removeth his dwelling.", "bbe": "By day, before their eyes, take out your vessels like those of one who is taken away: and go out in the evening before their eyes, like those who are taken away as prisoners.", "geneva": "Then shalt thou bring foorth thy stuffe by day in their sight as the stuffe of him that goeth into captiuitie: and thou shalt go forth at euen in their sight, as they that go foorth into captiuitie.", "wycliffe": "And thou schalt bere withoutforth thi vessels, as the vessels of a man passynge ouer bi dai, in the siyt of hem; sotheli thou schalt go out in the euentid bifore hem, as a man passynge forth goith out.", "rotherham": "Therefore shalt thou take forth thy baggage as baggage for exile, by day before their eyes,—and thou thyself, shalt go forth in the evening, before their eyes, like them who go forth to exile.", "darby": "And bring forth thy baggage by day in their sight, as a captive's baggage, and thou thyself, go forth at even in their sight as they that go forth into captivity.", "twenty": "", "jps": "And thou shalt bring forth thy stuff by day in their sight, as stuff for exile; and thou shalt go forth thyself at even in their sight, as when men go forth into exile.", "acv": "And thou shall bring forth thy stuff by day in their sight, as stuff for moving. And thou shall go forth thyself at evening in their sight, as when men go forth into exile.", "anderson": "", "haweis": "", "noyes": "And carry forth thy stuff, as stuff for removing, by day in their sight, and go forth at even in their sight, as they that go forth into captivity.", "webster": "Then shalt thou bring forth thy stuff by day in their sight, as stuff for removing: and thou shalt go forth at evening in their sight, as they that go forth into captivity.", "vulgate": "et efferes foras vasa tua quasi vasa transmigrantis per diem in conspectu eorum tu autem egredieris vespere coram eis sicut egreditur migrans;", "brenton": "And thou shalt carry forth thy baggage, baggage for captivity, by day before their eyes: and thou shalt go forth at even, as a captive goes forth, in their sight."}}, {"v": 5, "ref": "12:5", "o": "לְ/עֵינֵי/הֶ֖ם חֲתָר לְ/ךָ֣ בַ/קִּ֑יר וְ/הוֹצֵאתָ֖ בּֽ/וֹ", "en": {"kjv": "Dig thou through the wall in their sight, and carry out thereby.", "web": "Dig through the wall in their sight, and carry your stuff out that way.", "bsb": "As they watch, dig through the wall and carry your belongings out through it.", "asv": "Dig thou through the wall in their sight, and carry out thereby.", "ylt": "Before their eyes dig for thee through the wall, and thou hast brought forth by it.", "dra": "Dig thee a way through the wall before their eyes: and thou shalt go forth through it.", "bbe": "Make a hole in the wall, before their eyes, and go out through it.", "geneva": "Dig thou through the wall in their sight, and cary out thereby.", "wycliffe": "Bifore the iyen of hem digge the wal to thee, and thou", "rotherham": "Before their eyes, break thou forth by thyself through the wall,—and carry forth through it.", "darby": "Dig thou through the wall in their sight, and carry out thereby.", "twenty": "", "jps": "Dig thou through the wall in their sight, and carry out thereby.", "acv": "Dig thou through the wall in their sight, and carry out by that.", "anderson": "", "haweis": "", "noyes": "Before their eyes break thou through the wall, and carry forth thereby.", "webster": "Dig thou through the wall in their sight, and carry out thereby.", "vulgate": "ante oculos eorum perfodi tibi parietem et egredieris per eum;", "brenton": "Dig for thyself into the wall of the house, and thou shalt pass through it in their sight:"}}, {"v": 6, "ref": "12:6", "o": "לְ/עֵ֨ינֵי/הֶ֜ם עַל כָּתֵ֤ף תִּשָּׂא֙ בָּ/עֲלָטָ֣ה תוֹצִ֔יא פָּנֶ֣י/ךָ תְכַסֶּ֔ה וְ/לֹ֥א תִרְאֶ֖ה אֶת הָ/אָ֑רֶץ כִּֽי מוֹפֵ֥ת נְתַתִּ֖י/ךָ לְ/בֵ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "In their sight shalt thou bear it upon thy shoulders, and carry it forth in the twilight: thou shalt cover thy face, that thou see not the ground: for I have set thee for a sign unto the house of Israel.", "web": "In their sight you shall bear it on your shoulder, and carry it out in the dark; you shall cover your face, so that you don’t see the land: for I have set you for a sign to the house of Israel.", "bsb": "And as they watch, lift your bags to your shoulder and take them out at dusk; cover your face so that you cannot see the land. For I have made you a sign to the house of Israel.”", "asv": "In their sight shalt thou bear it upon thy shoulder, and carry it forth in the dark; thou shalt cover thy face, that thou see not the land: for I have set thee for a sign unto the house of Israel.", "ylt": "Before their eyes on the shoulder thou dost bear, in the darkness thou dost bring forth, thy face thou dost cover, and thou dost not see the earth, for a type I have given thee to the house of Israel.'", "dra": "In their sight thou shalt be carried out upon men's shoulders, thou shalt be carried out in the dark: thou shalt cover thy face, and shalt not see the ground: for I have set thee for a sign of things to come to the house of Israel.", "bbe": "And before their eyes, take your goods on your back and go out in the dark; go with your face covered: for I have made you a sign to the children of Israel.", "geneva": "In their sight shalt thou beare it vpon thy shoulders, and carie it foorth in the darke: thou shalt couer thy face that thou see not the earth: for I haue set thee as a signe vnto the house of Israel.", "wycliffe": "schalt go out thorouy it in the siyt of hem. Thou schalt be borun on schuldris, thou schalt be borun out in derknesse; thou schalt hile thi face, and thou schalt not se the erthe, for Y haue youe thee a signe", "rotherham": "Before their eyes, Upon the shoulder, shalt thou lift it. In thick darkness, take it forth, Thy face, shalt thou cover so that thou see not the land; For a sign, have I appointed thee to the house of Israel.", "darby": "In their sight shalt thou bear [it] upon [thy] shoulder, and carry it forth in the dark; thou shalt cover thy face, and thou shalt not see the ground: for I have appointed thee for a sign unto the house of Israel.", "twenty": "", "jps": "In their sight shalt thou bear it upon thy shoulder, and carry it forth in the darkness; thou shalt cover thy face, that thou see not the ground; for I have set thee for a sign unto the house of Israel.'", "acv": "Thou shall bear it upon thy shoulder in their sight, and carry it forth in the dark. Thou shall cover thy face, that thou not see the land. For I have set thee for a sign to the house of Israel.", "anderson": "", "haweis": "", "noyes": "In their sight bear it upon thy shoulders, and carry it forth in the twilight. Cover thy face, so that thou see not the ground; for I have made thee a sign to the house of Israel.", "webster": "In their sight shalt thou bear [it] upon [thy] shoulders, [and] carry [it] forth in the twilight: thou shalt cover thy face, that thou mayest not see the ground: for I have set thee [for] a sign to the house of Israel.", "vulgate": "in conspectu eorum in umeris portaberis in caligine effereris faciem tuam velabis et non videbis terram quia portentum dedi te domui Israhel;", "brenton": "thou shalt be lifted up on men's shoulders, and shalt go forth in secret: thou shalt cover thy face, and shalt not see the ground: because I have made thee a sign to the house of Israel."}}, {"v": 7, "ref": "12:7", "o": "וָ/אַ֣עַשׂ כֵּן֮ כַּ/אֲשֶׁ֣ר צֻוֵּיתִי֒ כֵּ֠לַ/י הוֹצֵ֜אתִי כִּ/כְלֵ֤י גוֹלָה֙ יוֹמָ֔ם וּ/בָ/עֶ֛רֶב חָתַֽרְתִּי לִ֥/י בַ/קִּ֖יר בְּ/יָ֑ד בָּ/עֲלָטָ֥ה הוֹצֵ֛אתִי עַל כָּתֵ֥ף נָשָׂ֖אתִי לְ/עֵינֵי/הֶֽם", "en": {"kjv": "And I did so as I was commanded: I brought forth my stuff by day, as stuff for captivity, and in the even I digged through the wall with mine hand; I brought it forth in the twilight, and I bare it upon my shoulder in their sight.", "web": "I did so as I was commanded: I brought out my stuff by day, as stuff for removing, and in the even I dug through the wall with my hand; I brought it out in the dark, and bore it on my shoulder in their sight.", "bsb": "So I did as I was commanded. I brought out my bags for exile by day, and in the evening I dug through the wall by hand. I took my belongings out at dusk, carrying them on my shoulder as they watched.", "asv": "And I did so as I was commanded: I brought forth my stuff by day, as stuff for removing, and in the even I digged through the wall with my hand; I brought it forth in the dark, and bare it upon my shoulder in their sight.", "ylt": "And I do so, as I have been commanded; my vessels I have brought forth as vessels of removal by day, and at even I have dug for me through the wall with the hand; in the darkness I have brought forth, on the shoulder I have borne away, before their eyes.", "dra": "I did therefore as he had commanded me: I brought forth my goods by day, as the goods of one that removeth: and in the evening I digged through the wall with my hand, and I went forth in the dark, and was carried on men's shoulders in their sight.", "bbe": "And I did as I was ordered: I took out my vessels by day, like those of one who is taken away, and in the evening I made a hole through the wall with a tent-pin; and in the dark I went out, taking my things on my back before their eyes.", "geneva": "And as I was commanded, so I brought forth my stuffe by day, as ye stuffe of one that goeth into captiuitie: and by night I digged through the wall with mine hand, and brought it forth in ye darke, and I bare it vpon my shoulder in their sight.", "wycliffe": "of thing to comynge to the hous of Israel. Therfor Y dide as the Lord comaundide to me; Y brouyte forth my vessels, as the vessels of a man passynge ouer bi dai, and in the euentid Y diggide a wal to me with hond; Y yede out in derknesse, and Y was borun on schuldris,", "rotherham": "And I did so, just as I was commanded, My baggage, took I forth as baggage for exile by day, and in the evening, I brake forth by myself through the wall, by force: in the twilight, I took it forth—on to my shoulder, I lifted it, before their eyes.", "darby": "And I did so as I was commanded: I brought forth my baggage by day, as a captive's baggage, and in the even I digged through the wall with my hand; I brought it forth in the dark, [and] bore it upon [my] shoulder, in their sight.", "twenty": "", "jps": "And I did so as I was commanded: I brought forth my stuff by day, as stuff for exile, and in the even I digged through the wall with my hand; I carried out in the darkness, and bore it upon my shoulder in their sight.", "acv": "And I did so as I was commanded. I brought forth my stuff by day, as stuff for moving, and in the evening I dug through the wall with my hand. I brought it forth in the dark, and bore it upon my shoulder in their sight.", "anderson": "", "haweis": "", "noyes": "And I did as I was commanded, I carried forth my stuff, as stuff for removing from the land, by day; and in the evening I broke through the wall with my hand; I carried it forth in the twilight; I took it upon my shoulder before their eyes.", "webster": "And I did so as I was commanded: I brought forth my stuff by day, as stuff for captivity, and in the evening I digged through the wall with my hand; I brought [it] forth in the twilight, [and] I bore [it] upon [my] shoulder in their sight.", "vulgate": "feci ergo sicut praeceperat mihi vasa mea protuli quasi vasa transmigrantis per diem et vespere perfodi mihi parietem manu in caligine egressus sum et in umeris portatus in conspectu eorum;", "brenton": "And I did thus according to all that he commanded me; and I carried forth my baggage for captivity by day, and in the evening I dug through the wall for myself, and went out secretly; I was taken up on men's shoulders before them."}}, {"v": 8, "ref": "12:8", "o": "וַ/יְהִ֧י דְבַר יְהוָ֛ה אֵלַ֖/י בַּ/בֹּ֥קֶר לֵ/אמֹֽר", "en": {"kjv": "And in the morning came the word of the Lord unto me, saying,", "web": "In the morning, Yahweh’s word came to me, saying,", "bsb": "And in the morning the word of the LORD came to me, saying,", "asv": "And in the morning came the word of Jehovah unto me, saying,", "ylt": "And there is a word of Jehovah unto me, in the morning, saying,", "dra": "And the word of the Lord came to me in the morning, saying:", "bbe": "And in the morning the word of the Lord came to me, saying,", "geneva": "And in the morning came the word of the Lord vnto me, saying,", "wycliffe": "in the siyt of hem. And the word of the Lord was maad eerli to me,", "rotherham": "Then came the word of Yahweh unto me in the morning, saying:", "darby": "And in the morning the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And in the morning came the word of HaShem unto me, saying:", "acv": "And in the morning the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me in the morning, and said:", "webster": "And in the morning came the word of the LORD to me, saying,", "vulgate": "et factus est sermo Domini ad me mane dicens;", "brenton": "And the word of the Lord came to me in the morning, saying,"}}, {"v": 9, "ref": "12:9", "o": "בֶּן אָדָ֕ם הֲ/לֹ֨א אָמְר֥וּ אֵלֶ֛י/ךָ בֵּ֥ית יִשְׂרָאֵ֖ל בֵּ֣ית הַ/מֶּ֑רִי מָ֖ה אַתָּ֥ה עֹשֶֽׂה", "en": {"kjv": "Son of man, hath not the house of Israel, the rebellious house, said unto thee, What doest thou?", "web": "Son of man, has not the house of Israel, the rebellious house, said to you, What are you doing?", "bsb": "“Son of man, hasn’t the rebellious house of Israel asked you, ‘What are you doing?’", "asv": "Son of man, hath not the house of Israel, the rebellious house, said unto thee, What doest thou?", "ylt": "`Son of man, have they not said unto thee--the house of Israel--the rebellious house--What art thou doing?", "dra": "Son of man, hath not the house of Israel, the provoking house, said to thee: What art thou doing?", "bbe": "Son of man, has not Israel, the uncontrolled people, said to you, What are you doing?", "geneva": "Sonne of man, hath not the house of Israel, the rebellious house, sayde vnto thee, What doest thou?", "wycliffe": "and he seide, Sone of man, whether the hous of Israel, the hous terrynge to wraththe, seiden not to thee, What doist thou?", "rotherham": "Son of man, Have not the house of Israel the perverse house, said unto thee,— What art thou doing?", "darby": "Son of man, hath not the house of Israel, the rebellious house, said unto thee, What doest thou?", "twenty": "", "jps": "'Son of man, hath not the house of Israel, the rebellious house, said unto thee: What doest thou?", "acv": "Son of man, has not the house of Israel, the rebellious house, said to thee, What are thou doing?", "anderson": "", "haweis": "", "noyes": "Son of man, hath not the house of Israel, the rebellious house, said to thee, \"What doest thou?\"", "webster": "Son of man, hath not the house of Israel, the rebellious house, said to thee, What doest thou?", "vulgate": "fili hominis numquid non dixerunt ad te domus Israhel domus exasperans quid tu facis;", "brenton": "Son of man, have not the house of Israel, the provoking house, said to thee, What doest thou?"}}, {"v": 10, "ref": "12:10", "o": "אֱמֹ֣ר אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהֹוִ֑ה הַ/נָּשִׂ֞יא הַ/מַּשָּׂ֤א הַ/זֶּה֙ בִּ/יר֣וּשָׁלִַ֔ם וְ/כָל בֵּ֥ית יִשְׂרָאֵ֖ל אֲשֶׁר הֵ֥מָּה בְ/תוֹכָֽ/ם", "en": {"kjv": "Say thou unto them, Thus saith the Lord God; This burden concerneth the prince in Jerusalem, and all the house of Israel that are among them.", "web": "Say to them, Thus says the Lord Yahweh: This burden concerns the prince in Jerusalem, and all the house of Israel among whom they are.", "bsb": "Tell them that this is what the Lord GOD says: ‘This burden concerns the prince in Jerusalem and all the house of Israel who are there.’", "asv": "Say thou unto them, Thus saith the Lord Jehovah: This burden concerneth the prince in Jerusalem, and all the house of Israel among whom they are.", "ylt": "say unto them, Thus said the Lord Jehovah: `The prince is this burden in Jerusalem, and all the house of Israel who are in their midst.", "dra": "Say to them: Thus saith the Lord God: This burden concerneth my prince that is in Jerusalem, and all the house of Israel, that are among them.", "bbe": "You are to say to them, This is what the Lord has said: This word has to do with the ruler in Jerusalem and all the children of Israel in it.", "geneva": "But say thou vnto them, Thus saith the Lord God, This burden concerneth the chiefe in Ierusalem, and all the house of Israel that are among them.", "wycliffe": "Seie thou to hem, The Lord God seith these thingis, This birthun is on the duyk, which is in Jerusalem, and on al the hous of Israel, which is in the myddis of hem.", "rotherham": "Say unto them, Thus, saith My Lord, Yahweh,— [For] the Bearer, is this burden, in Jerusalem, and [for] all the house of Israel such as are in their midst.", "darby": "Say unto them, Thus saith the Lord Jehovah: This burden [concerneth] the prince in Jerusalem, and all the house of Israel that are among them.", "twenty": "", "jps": "Say thou unto them: Thus saith the L-rd GOD: Concerning the prince, even this burden, in Jerusalem, and all the house of Israel among whom they are,", "acv": "Say thou to them, Thus says the lord Jehovah: This burden concerns the ruler in Jerusalem, and all the house of Israel among whom they are.", "anderson": "", "haweis": "", "noyes": "Say to them, Thus saith the Lord Jehovah: This burden concerneth the prince in Jerusalem, and all the house of Israel that is therein.", "webster": "Say thou to them, Thus saith the Lord GOD, This burden [concerneth] the prince in Jerusalem, and all the house of Israel that [are] among them.", "vulgate": "dic ad eos haec dicit Dominus Deus super ducem onus istud qui est in Hierusalem et super omnem domum Israhel quae est in medio eorum;", "brenton": "Say to them, Thus saith the Lord God, the Prince and the Ruler in Israel, even to all the house of Israel who are in the midst of them:"}}, {"v": 11, "ref": "12:11", "o": "אֱמֹ֖ר אֲנִ֣י מֽוֹפֶתְ/כֶ֑ם כַּ/אֲשֶׁ֣ר עָשִׂ֗יתִי כֵּ֚ן יֵעָשֶׂ֣ה לָ/הֶ֔ם בַּ/גּוֹלָ֥ה בַ/שְּׁבִ֖י יֵלֵֽכוּ", "en": {"kjv": "Say, I am your sign: like as I have done, so shall it be done unto them: they shall remove and go into captivity.", "web": "Say, I am your sign: like as I have done, so shall it be done to them; they shall go into exile, into captivity.", "bsb": "You are to say, ‘I am a sign to you.’ Just as it happened here, so will it be done to them; they will go into exile as captives.", "asv": "Say, I am your sign: like as I have done, so shall it be done unto them; they shall go into exile, into captivity.", "ylt": "Say: I am your type; as I have done so it is done to them, into a removal, into a captivity, they do go.", "dra": "Say: I am a sign of things to come to you: as I have done, so shall it be done to them: they shall be removed from their dwellings, and go into captivity.", "bbe": "Say, I am your sign: as I have done, so will it be done to them: they will go away as prisoners.", "geneva": "Say, I am your signe: like as I haue done, so shall it be done vnto them: they shall goe into bondage and captiuitie.", "wycliffe": "Seie thou, Y am youre signe of thing to comynge; as Y dide, so it schal be don to hem; thei schulen go in to passynge ouer, and in to caitifte.", "rotherham": "Say, I, am your sign: As I have done, so. shall it be done to them, Into exile—into captivity, shall they go.", "darby": "Say, I am your sign: as I have done, so shall it be done unto them: they shall go into exile, into captivity.", "twenty": "", "jps": "say: I am your sign: like as I have done, so shall it be done unto them--they shall go into exile, into captivity.", "acv": "Say, I am your sign. Just as I have done, so shall it be done to them. They shall go into exile, into captivity.", "anderson": "", "haweis": "", "noyes": "Say, I am your sign. As I have done, so shall it be done to them. They shall remove and go into captivity.", "webster": "Say, I [am] your sign: as I have done, so shall it be done to them: they shall remove [and] go into captivity.", "vulgate": "dic ego portentum vestrum quomodo feci sic fiet illis in transmigrationem et captivitatem ibunt;", "brenton": "say, I am performing signs: as I have done, so shall it be to him: they shall go into banishment and captivity."}}, {"v": 12, "ref": "12:12", "o": "וְ/הַ/נָּשִׂ֨יא אֲשֶׁר בְּ/תוֹכָ֜/ם אֶל כָּתֵ֤ף יִשָּׂא֙ בָּ/עֲלָטָ֣ה וְ/יֵצֵ֔א בַּ/קִּ֥יר יַחְתְּר֖וּ לְ/ה֣וֹצִיא ב֑/וֹ פָּנָ֣י/ו יְכַסֶּ֔ה יַ֗עַן אֲשֶׁ֨ר לֹא יִרְאֶ֥ה לַ/עַ֛יִן ה֖וּא אֶת הָ/אָֽרֶץ", "en": {"kjv": "And the prince that is among them shall bear upon his shoulder in the twilight, and shall go forth: they shall dig through the wall to carry out thereby: he shall cover his face, that he see not the ground with his eyes.", "web": "The prince who is among them shall bear on his shoulder in the dark, and shall go out: they shall dig through the wall to carry out thereby: he shall cover his face, because he shall not see the land with his eyes.", "bsb": "And at dusk the prince among them will lift his bags to his shoulder and go out. They will dig through the wall to bring him out. He will cover his face so he cannot see the land.", "asv": "And the prince that is among them shall bear upon his shoulder in the dark, and shall go forth: they shall dig through the wall to carry out thereby: he shall cover his face, because he shall not see the land with his eyes.", "ylt": "As to the prince who is in their midst, on the shoulder he beareth in the darkness, and he goeth forth, through the wall they dig to bring forth by it, his face he covereth, that he may not look on the very surface of the land.", "dra": "And the prince that is in the midst of them, shall be carried on shoulders, he shall go forth in the dark: they shall dig through the wall to bring him out: his face shall be covered, that he may not see the ground with his eyes.", "bbe": "And the ruler who is among them will take his goods on his back in the dark and go out: he will make a hole in the wall through which to go out: he will have his face covered so that he may not be seen.", "geneva": "And the chiefest that is among them, shall beare vpon his shoulder in the darke, and shall goe forth: they shall digge through the wall, to cary out thereby: he shall couer his face, that he see not the ground with his eies.", "wycliffe": "And the duyk which is in the myddis of hem, schal be borun out on schuldris, and he schal go out in derknesse; thei schulen digge the wal, and lede hym out; his face schal be hilid, that he se not with iye the erthe.", "rotherham": "Yea, the Bearer who is in their midst, Upon his shoulder, shall lift it. In thick darkness, shall he go forth, Through the wall, shall they break to bear forth through it,— His face, shall he cover, to the end that, his own eye, may not see the land.", "darby": "And the prince that is among them shall bear upon [his] shoulder in the dark, and shall go forth; they shall dig through the wall to carry out thereby; he shall cover his face, that he see not the land with [his] eyes.", "twenty": "", "jps": "And the prince that is among them shall bear upon his shoulder, and go forth in the darkness; they shall dig through the wall to carry out thereby; he shall cover his face, that he see not the ground with his eyes.", "acv": "And the ruler who is among them shall bear upon his shoulder in the dark, and shall go forth. They shall dig through the wall to carry out by it. He shall cover his face, because he shall not see the land with his eyes.", "anderson": "", "haweis": "", "noyes": "And the prince that is among them shall bear upon his shoulder in the twilight, and shall go forth. They shall break through the wall to carry forth thereby; he shall cover his face, that he see not the ground with his eyes.", "webster": "And the prince that [is] among them shall bear upon [his] shoulder in the twilight, and shall go forth: they shall dig through the wall to carry out thereby: he shall cover his face, that he may not see the ground with [his] eyes.", "vulgate": "et dux qui est in medio eorum in umeris portabitur in caligine egredietur parietem perfodient ut educant eum facies eius operietur ut non videat oculo terram;", "brenton": "And the prince in the midst of them shall be borne upon shoulders, and shall go forth in secret through the wall, and shall dig so that he may go forth thereby: he shall cover his face, that he may not be seen by any eye, and he himself shall not see the ground."}}, {"v": 13, "ref": "12:13", "o": "וּ/פָרַשְׂתִּ֤י אֶת רִשְׁתִּ/י֙ עָלָ֔י/ו וְ/נִתְפַּ֖שׂ בִּ/מְצֽוּדָתִ֑/י וְ/הֵבֵאתִ֨י אֹת֤/וֹ בָבֶ֨לָ/ה֙ אֶ֣רֶץ כַּשְׂדִּ֔ים וְ/אוֹתָ֥/הּ לֹֽא יִרְאֶ֖ה וְ/שָׁ֥ם יָמֽוּת", "en": {"kjv": "My net also will I spread upon him, and he shall be taken in my snare: and I will bring him to Babylon to the land of the Chaldeans; yet shall he not see it, though he shall die there.", "web": "My net also will I spread on him, and he shall be taken in my snare; and I will bring him to Babylon to the land of the Chaldeans; yet shall he not see it, though he shall die there.", "bsb": "But I will spread My net over him, and he will be caught in My snare. I will bring him to Babylon, the land of the Chaldeans; yet he will not see it, and there he will die.", "asv": "My net also will I spread upon him, and he shall be taken in my snare; and I will bring him to Babylon to the land of the Chaldeans; yet shall he not see it, though he shall die there.", "ylt": "And I have spread My net for him, and he hath been caught in My snare, and I have brought him in to Babylon, the land of the Chaldeans, and it he doth not see--and there doth he die.", "dra": "And I will spread my net over him, and he shall be taken in my net: and I will bring him into Babylon, into the land of the Chaldeans, and he shall not see it, and there he shall die.", "bbe": "And my net will be stretched out on him, and he will be taken in my cords: and I will take him to Babylon to the land of the Chaldaeans; but he will not see it, and there death will come to him.", "geneva": "My net also will I spread vpon him, and he shall be taken in my net, and I will bring him to Babel to the lande of the Caldeans, yet shall he not see it, though he shall dye there.", "wycliffe": "And Y schal stretche forth my net on hym, and he schal be takun in my net; and Y schal lede hym in to Babiloyne, in to the lond of Caldeis, and he schal not se that lond, and he schal die there.", "rotherham": "Then will I spread my net over him, and he shall be taken in my snare; And I will take him to Babylon. in the land of the Chaldeans, The which, indeed, he shall not see. And yet there, shall he die!", "darby": "And I will spread my net upon him, and he shall be taken in my snare; and I will bring him to Babylon to the land of the Chaldeans; but he shall not see it, and there shall he die.", "twenty": "", "jps": "My net also will I spread upon him, and he shall be taken in My snare; and I will bring him to Babylon to the land of the Chaldeans; yet shall he not see it, though he shall die there.", "acv": "I will also spread my net upon him, and he shall be taken in my snare. And I will bring him to Babylon to the land of the Chaldeans, yet he shall not see it, though he shall die there.", "anderson": "", "haweis": "", "noyes": "I will also spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, into the land of the Chaldaeans; yet he shall not see it, though he shall die there.", "webster": "My net also will I spread upon him, and he shall be taken in my snare: and I will bring him to Babylon [to] the land of the Chaldeans, yet shall he not see it, though he shall die there.", "vulgate": "et extendam rete meum super illum et capietur in sagena mea et adducam eum in Babylonem in terram Chaldeorum et ipsam non videbit ibique morietur;", "brenton": "And I will spread out my net upon him, and he shall be caught in my toils: and I will bring him to Babylon to the land of the Chaldeans; but he shall not see it, though he shall die there."}}, {"v": 14, "ref": "12:14", "o": "וְ/כֹל֩ אֲשֶׁ֨ר סְבִיבֹתָ֥י/ו עזר/ה עֶזְר֛/וֹ וְ/כָל אֲגַפָּ֖י/ו אֱזָרֶ֣ה לְ/כָל ר֑וּחַ וְ/חֶ֖רֶב אָרִ֥יק אַחֲרֵי/הֶֽם", "en": {"kjv": "And I will scatter toward every wind all that are about him to help him, and all his bands; and I will draw out the sword after them.", "web": "I will scatter toward every wind all who are around him to help him, and all his bands; and I will draw out the sword after them.", "bsb": "And I will scatter to every wind all the attendants around him and all his troops, and I will draw a sword to chase after them.", "asv": "And I will scatter toward every wind all that are round about him to help him, and all his bands; and I will draw out the sword after them.", "ylt": "`And all who are round about him to help him, and all his bands, I do scatter to every wind, and a sword I draw out after them.", "dra": "And all that are about him, his guards, and his troops I will scatter into every wind: and I will draw out the sword after them.", "bbe": "And all his helpers round about him and all his armies I will send in flight to every wind; and I will let loose a sword after them.", "geneva": "And I will scatter toward euerie winde all that are about him to helpe him, and all his garisons, and I will drawe out the sworde after them.", "wycliffe": "And Y schal scatere in to ech wynd alle men that ben aboute hym, his help, and hise cumpenyes; and Y schal draw out the swerd aftir hem.", "rotherham": "And all who are round about him to help him and all his troops, will I scatter to every wind,—and, a sword, will I make bare after them.", "darby": "And I will scatter toward every wind all that are about him to help him, and all his troops; and I will draw out the sword after them.", "twenty": "", "jps": "And I will disperse toward every wind all that are round about him to help him, and all his troops; and I will draw out the sword after them.", "acv": "And I will scatter toward every wind all who are round about him to help him, and all his groups. And I will draw out the sword after them.", "anderson": "", "haweis": "", "noyes": "And all that are round about him to help him, and all his bands, will I scatter to every wind; and I will draw out the sword after them.", "webster": "And I will scatter towards every wind all that [are] about him to help him, and all his bands; and I will draw out the sword after them.", "vulgate": "et omnes qui circa eum sunt praesidium eius et agmina eius dispergam in omnem ventum et gladium evaginabo post eos;", "brenton": "And I will scatter to every wind all his assistants round about him, and all that help him; and I will draw out a sword after them;"}}, {"v": 15, "ref": "12:15", "o": "וְ/יָדְע֖וּ כִּֽי אֲנִ֣י יְהוָ֑ה בַּ/הֲפִיצִ֤/י אוֹתָ/ם֙ בַּ/גּוֹיִ֔ם וְ/זֵרִיתִ֥י אוֹתָ֖/ם בָּ/אֲרָצֽוֹת", "en": {"kjv": "And they shall know that I am the Lord, when I shall scatter them among the nations, and disperse them in the countries.", "web": "They shall know that I am Yahweh, when I shall disperse them among the nations, and scatter them through the countries.", "bsb": "And they will know that I am the LORD, when I disperse them among the nations and scatter them throughout the countries.", "asv": "And they shall know that I am Jehovah, when I shall disperse them among the nations, and scatter them through the countries.", "ylt": "And they have known that I am Jehovah, in My scattering them among nations, and I have spread them through lands;", "dra": "And they shall know that I am the Lord, when I shall have dispersed them among the nations, and scattered them in the countries.", "bbe": "And they will be certain that I am the Lord, when I send them in flight among the nations, driving them out through the countries.", "geneva": "And they shall knowe that I am the Lord, when I shall scatter them among the nations, and disperse them in the countreis.", "wycliffe": "And thei schulen wite, that Y am the Lord, whanne Y schal scatere hem among hethene men, and schal sowe hem abrood in londis.", "rotherham": "So shall they know that, I, am Yahweh,— By my dispersing them among the nations, And scattering them throughout the lands.", "darby": "And they shall know that I [am] Jehovah when I shall scatter them among the nations and disperse them through the countries.", "twenty": "", "jps": "And they shall know that I am HaShem, when I shall scatter them among the nations, and disperse them in the countries.", "acv": "And they shall know that I am Jehovah, when I shall disperse them among the nations, and scatter them through the countries.", "anderson": "", "haweis": "", "noyes": "And they shall know that I am Jehovah, when I shall disperse them among the nations, and scatter them in the countries.", "webster": "And they shall know that I [am] the LORD, when I shall scatter them among the nations, and disperse them in the countries.", "vulgate": "et scient quia ego Dominus quando dispersero illos in gentibus et disseminavero eos in terris;", "brenton": "And they shall know that I am the Lord, when I have scattered them among the nations; and I will disperse them in the countries."}}, {"v": 16, "ref": "12:16", "o": "וְ/הוֹתַרְתִּ֤י מֵ/הֶם֙ אַנְשֵׁ֣י מִסְפָּ֔ר מֵ/חֶ֖רֶב מֵ/רָעָ֣ב וּ/מִ/דָּ֑בֶר לְמַ֨עַן יְסַפְּר֜וּ אֶת כָּל תּוֹעֲבֽוֹתֵי/הֶ֗ם בַּ/גּוֹיִם֙ אֲשֶׁר בָּ֣אוּ שָׁ֔ם וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the heathen whither they come; and they shall know that I am the Lord.", "web": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the nations where they come; and they shall know that I am Yahweh.", "bsb": "But I will spare a few of them from sword and famine and plague, so that in the nations to which they go, they can recount all their abominations. Then they will know that I am the LORD.”", "asv": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the nations whither they come; and they shall know that I am Jehovah.", "ylt": "and I have left of them, a few in number, from the sword, from the famine, and from the pestilence, so that they recount all their abominations among the nations whither they have come, and they have known that I am Jehovah.'", "dra": "And I will leave a few men of them from the sword, and from the famine, and from the pestilence: that they may declare all their wicked deeds among the nations whither they shall go: and they shall know that I am the Lord.", "bbe": "But a small number of them I will keep from the sword, from the need of food, and from disease, so that they may make clear all their disgusting ways among the nations where they come; and they will be certain that I am the Lord.", "geneva": "But I will leaue a litle nomber of them from the sworde, from the famine, and from the pestilence, that they may declare all these abominations among the heathen, where they come, and they shall knowe, that I am the Lord.", "wycliffe": "And Y schal leue of hem a fewe men fro swerd, and hungur, and pestilence, that thei telle out alle the grete trespassis of hem among hethene men, to which thei schulen entre; and thei schulen wite, that Y am the Lord.", "rotherham": "Yet will I leave remaining of them men easily counted, from the sword from the famine and from the pestilence,—that they may recount all their abominations among the nations whither they have come, So shall they know that, I, am Yahweh.", "darby": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the nations whither they shall come; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the nations whither they come; and they shall know that I am HaShem.'", "acv": "But I will leave a few men of them from the sword, from the famine, and from the pestilence, that they may declare all their abominations among the nations where they come. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the heathen, whither they come; and they shall know that I am Jehovah.", "webster": "But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the heathen whither they come; and they shall know that I [am] the LORD.", "vulgate": "et relinquam ex eis viros paucos a gladio et fame et pestilentia ut narrent omnia scelera eorum in gentibus ad quas ingredientur et scient quia ego Dominus;", "brenton": "And I will leave of them a few men in number spared from the sword, and from famine, and pestilence; that they may declare all their iniquities among the nations whither they have gone; and they shall know that I am the Lord."}}, {"v": 17, "ref": "12:17", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came to me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Moreover, the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came to me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moreouer, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me, saying:", "darby": "And the word of Jehovah came to me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came to me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 18, "ref": "12:18", "o": "בֶּן אָדָ֕ם לַחְמְ/ךָ֖ בְּ/רַ֣עַשׁ תֹּאכֵ֑ל וּ/מֵימֶ֕י/ךָ בְּ/רָגְזָ֥ה וּ/בִ/דְאָגָ֖ה תִּשְׁתֶּֽה", "en": {"kjv": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with carefulness;", "web": "Son of man, eat your bread with quaking, and drink your water with trembling and with fearfulness;", "bsb": "“Son of man, eat your bread with trembling, and drink your water with quivering and anxiety.", "asv": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with fearfulness;", "ylt": "`Son of man, thy bread in haste thou dost eat, and thy water with trembling and with fear thou dost drink;", "dra": "Son of man, eat thy bread in trouble and drink thy water in hurry and sorrow.", "bbe": "Son of man, take your food with shaking fear, and your water with trouble and care;", "geneva": "Sonne of man, eate thy bread with trembling and drinke thy water with trouble, and with carefulnesse,", "wycliffe": "and he seide, Thou, sone of man, ete thi breed in disturblyng, but also drynke thi water in haaste and mourening.", "rotherham": "Son of man, Thy bread with trembling, shalt thou eat,— And, thy water in agitation and in fear, shalt thou drink.", "darby": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with anxiety;", "twenty": "", "jps": "'Son of man, eat thy bread with quaking, and drink thy water with trembling and with anxiety;", "acv": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with fearfulness.", "anderson": "", "haweis": "", "noyes": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with carefulness;", "webster": "Son of man, eat thy bread with quaking, and drink thy water with trembling and with solicitude.", "vulgate": "fili hominis panem tuum in conturbatione comede sed et aquam tuam in festinatione et maerore bibe;", "brenton": "Son of man, eat thy bread with sorrow, and drink thy water with torment and affliction."}}, {"v": 19, "ref": "12:19", "o": "וְ/אָמַרְתָּ֣ אֶל עַ֣ם הָ/אָ֡רֶץ כֹּֽה אָמַר֩ אֲדֹנָ֨/י יְהוִ֜ה לְ/יוֹשְׁבֵ֤י יְרוּשָׁלִַ֨ם֙ אֶל אַדְמַ֣ת יִשְׂרָאֵ֔ל לַחְמָ/ם֙ בִּ/דְאָגָ֣ה יֹאכֵ֔לוּ וּ/מֵֽימֵי/הֶ֖ם בְּ/שִׁמָּמ֣וֹן יִשְׁתּ֑וּ לְמַ֜עַן תֵּשַׁ֤ם אַרְצָ/הּ֙ מִ/מְּלֹאָ֔/הּ מֵ/חֲמַ֖ס כָּֽל הַ/יֹּשְׁבִ֥ים בָּֽ/הּ", "en": {"kjv": "And say unto the people of the land, Thus saith the Lord God of the inhabitants of Jerusalem, and of the land of Israel; They shall eat their bread with carefulness, and drink their water with astonishment, that her land may be desolate from all that is therein, because of the violence of all them that dwell therein.", "web": "and tell the people of the land, Thus says the Lord Yahweh concerning the inhabitants of Jerusalem, and the land of Israel: They shall eat their bread with fearfulness, and drink their water in dismay, that her land may be desolate, and all that is therein, because of the violence of all those who dwell therein.", "bsb": "Then tell the people of the land that this is what the Lord GOD says about those living in Jerusalem and in the land of Israel: ‘They will eat their bread with anxiety and drink their water in dread, for their land will be stripped of everything in it because of the violence of all who dwell in it.", "asv": "and say unto the people of the land, Thus saith the Lord Jehovah concerning the inhabitants of Jerusalem, and the land of Israel: They shall eat their bread with fearfulness, and drink their water in dismay, that her land may be desolate, and despoiled of all that is therein, because of the violence of all them that dwell therein.", "ylt": "and thou hast said unto the people of the land, Thus said the Lord Jehovah concerning the inhabitants of Jerusalem, concerning the land of Israel: Their bread with fear they do eat, and their water with astonishment drink, because its land is desolate, because of its fulness, because of the violence of all who are dwelling in it.", "dra": "And say to the people of the land: Thus saith the Lord God to them that dwell in Jerusalem in the land of Israel: They shall eat their bread in care, and drink their water in desolation: that the land may become desolate from the multitude that is therein, for the iniquity of all that dwell therein.", "bbe": "And say to the people of the land, This is what the Lord has said about the people of Jerusalem and the land of Israel: They will take their food with care and their drink with wonder, so that all the wealth of their land may be taken from it because of the violent ways of the people living in it.", "geneva": "And say vnto the people of the land, Thus saith the Lord God of the inhabitants of Ierusalem, and of the lande of Israel, They shall eate their bread with carefulnes, and drinke their water with desolation: for the lande shall bee desolate from her abundance because of the crueltie of them that dwell therein.", "wycliffe": "And thou schalt seie to the puple of the lond, The Lord God seith these thingis to hem that dwellen in Jerusalem, in the lond of Israel, Thei schulen ete her breed in angwisch, and thei schulen drynke her watir in desolacioun; that the lond be desolat of his multitude, for the wickidnesse of alle men that dwellen ther ynne.", "rotherham": "Then shalt thou say unto the people of the land, Thus saith My Lord Yahweh concerning the inhabitants of Jerusalem upon the soil of Israel, Their bread with anxious care, shall they eat, And, their water in astonishment, shall they drink,— That her land, may be deserted, of her fulness, because of the violence of all them who dwell therein:", "darby": "and say unto the people of the land, Thus saith the Lord Jehovah concerning the inhabitants of Jerusalem, in the land of Israel: They shall eat their bread with anxiety, and drink their water with astonishment, because her land shall be left desolate of all that is in it, for the violence of all them that dwell therein.", "twenty": "", "jps": "and say unto the people of the land: Thus saith the L-rd GOD concerning the inhabitants of Jerusalem in the land of Israel. They shall eat their bread with anxiety, and drink their water with appalment, that her land may be desolate from all that is therein, because of the violence of all them that dwell therein.", "acv": "And say to the people of the land, Thus says the lord Jehovah concerning the inhabitants of Jerusalem, and the land of Israel: They shall eat their bread with fearfulness, and drink their water in dismay, that her land may be desolate of all that is in it, because of the violence of all those who dwell therein.", "anderson": "", "haweis": "", "noyes": "and say to the people of the land: Thus saith the Lord Jehovah concerning the inhabitants of Jerusalem in the land of Israel; their bread shall they eat with carefulness, and their water shall they drink with astonishment; that their land may be desolate from all that is therein, because of the violence of them that dwell in it.", "webster": "And say to the people of the land, Thus saith the Lord GOD of the inhabitants of Jerusalem, [and] of the land of Israel; They shall eat their bread with solicitude, and drink their water with astonishment, that her land may be desolate from all that is therein, because of the violence of all them that dwell therein.", "vulgate": "et dices ad populum terrae haec dicit Dominus Deus ad eos qui habitant in Hierusalem in terra Israhel panem suum in sollicitudine comedent et aquam suam in desolatione bibent ut desoletur terra a multitudine sua propter iniquitatem omnium qui habitant in ea;", "brenton": "And thou shalt say to the people of the land, Thus saith the Lord to the inhabitants of Jerusalem, on the land of Israel; They shall eat their bread in scarcity, and shall drink their water in desolation, that the land may be desolate with all that it contains: for all that dwell in it are ungodly."}}, {"v": 20, "ref": "12:20", "o": "וְ/הֶ/עָרִ֤ים הַ/נּֽוֹשָׁבוֹת֙ תֶּחֱרַ֔בְנָה וְ/הָ/אָ֖רֶץ שְׁמָמָ֣ה תִֽהְיֶ֑ה וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And the cities that are inhabited shall be laid waste, and the land shall be desolate; and ye shall know that I am the Lord.", "web": "The cities that are inhabited shall be laid waste, and the land shall be a desolation; and you shall know that I am Yahweh.", "bsb": "The inhabited cities will be laid waste, and the land will become desolate. Then you will know that I am the LORD.’”", "asv": "And the cities that are inhabited shall be laid waste, and the land shall be a desolation; and ye shall know that I am Jehovah.", "ylt": "And the cities that are inhabited are laid waste, and the land is a desolation, and ye have known that I am Jehovah.'", "dra": "And the cities that are now inhabited shall be laid waste, and the land shall be desolate: and you shall know that I am the Lord.", "bbe": "And the peopled towns will be made waste, and the land will become a wonder; and you will be certain that I am the Lord.", "geneva": "And the cities that are inhabited, shall be left voyde, and the land shall be desolate, and yee shall knowe that I am the Lord.", "wycliffe": "And citees that ben now enhabitid, shulen be desolat, and the lond schal be forsakun; and ye schulen wite, that Y am the Lord.", "rotherham": "Yea, the cities that are inhabited, shall be laid waste, And, the land, shall become, an astonishment,— So shall ye know that, I, am Yahweh.", "darby": "And the cities that are inhabited shall be laid waste, and the land shall be a desolation; and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "And the cities that are inhabited shall be laid waste, and the land shall be desolate; and ye shall know that I am HaShem.'", "acv": "And the cities that are inhabited shall be laid waste, and the land shall be a desolation. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And the inhabited cities shall be laid waste, and the land shall be desolate, that ye may know that I am Jehovah.", "webster": "And the cities that are inhabited shall be laid waste, and the land shall be desolate; and ye shall know that I [am] the LORD.", "vulgate": "et civitates quae nunc habitantur desolatae erunt terraque deserta et scietis quia ego Dominus;", "brenton": "And their inhabited cities shall be laid utterly waste, and the land shall be desolate; and ye shall know that I am the Lord."}}, {"v": 21, "ref": "12:21", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 22, "ref": "12:22", "o": "בֶּן אָדָ֗ם מָֽה הַ/מָּשָׁ֤ל הַ/זֶּה֙ לָ/כֶ֔ם עַל אַדְמַ֥ת יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר יַֽאַרְכוּ֙ הַ/יָּמִ֔ים וְ/אָבַ֖ד כָּל חָזֽוֹן", "en": {"kjv": "Son of man, what is that proverb that ye have in the land of Israel, saying, The days are prolonged, and every vision faileth?", "web": "Son of man, what is this proverb that you have in the land of Israel, saying, The days are prolonged, and every vision fails?", "bsb": "“Son of man, what is this proverb that you have in the land of Israel: ‘The days go by, and every vision fails’?", "asv": "Son of man, what is this proverb that ye have in the land of Israel, saying, The days are prolonged, and every vision faileth?", "ylt": "`Son of man, what is this simile to you, concerning the land of Israel, saying, Prolonged are the days, and perished hath every vision?", "dra": "Son of man, what is this proverb that you have in the land of Israel? saying: The days shall be prolonged, and every vision shall fail.", "bbe": "Son of man, what is this saying which you have about the land of Israel, The time is long and every vision comes to nothing?", "geneva": "Sonne of man, what is that prouerbe that you haue in the land of Israel, saying, The dayes are prolonged and all visions faile?", "wycliffe": "and he seide, Sone of man, what is this prouerbe to you, of men seiynge in the lond of Israel, Daies schulen be differrid in to long tyme, and ech visioun shal perische?", "rotherham": "Son of man What is this proverb ye have, concerning the soil of Israel, saying,— The days, are prolonged, Therefore shall every vision come to nought?", "darby": "Son of man, what is that proverb which ye have in the land of Israel, saying, The days shall be prolonged, and every vision faileth?", "twenty": "", "jps": "'Son of man, what is that proverb that ye have in the land of Israel, saying: The days are prolonged, and every vision faileth?", "acv": "Son of man, what is this proverb that ye have in the land of Israel, saying, The days are prolonged, and every vision fails?", "anderson": "", "haweis": "", "noyes": "Son of man, what meaneth that proverb which ye have in the land of Israel, saying, \"The days are delayed, and every vision faileth\"?", "webster": "Son of man, what [is] that proverb [that] ye have in the land of Israel, saying, The days are prolonged, and every vision faileth?", "vulgate": "fili hominis quod est proverbium istud vobis in terra Israhel dicentium in longum differentur dies et peribit omnis visio;", "brenton": "Son of man, what is your parable on the land of Israel, that ye say, The days are long, the vision has perished?"}}, {"v": 23, "ref": "12:23", "o": "לָ/כֵ֞ן אֱמֹ֣ר אֲלֵי/הֶ֗ם כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִשְׁבַּ֨תִּי֙ אֶת הַ/מָּשָׁ֣ל הַ/זֶּ֔ה וְ/לֹֽא יִמְשְׁל֥וּ אֹת֛/וֹ ע֖וֹד בְּ/יִשְׂרָאֵ֑ל כִּ֚י אִם דַּבֵּ֣ר אֲלֵי/הֶ֔ם קָֽרְבוּ֙ הַ/יָּמִ֔ים וּ/דְבַ֖ר כָּל חָזֽוֹן", "en": {"kjv": "Tell them therefore, Thus saith the Lord God; I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say unto them, The days are at hand, and the effect of every vision.", "web": "Tell them therefore, Thus says the Lord Yahweh: I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but tell them, The days are at hand, and the fulfillment of every vision.", "bsb": "Therefore tell them that this is what the Lord GOD says: ‘I will put an end to this proverb, and in Israel they will no longer recite it.’ But say to them: ‘The days are at hand when every vision will be fulfilled.", "asv": "Tell them therefore, Thus saith the Lord Jehovah: I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say unto them, The days are at hand, and the fulfilment of every vision.", "ylt": "therefore say unto them: Thus said the Lord Jehovah: I have caused this simile to cease, And they use it not as a simile again in Israel, But speak to them: Drawn near have the days, And spoken hath every vision.", "dra": "Say to them therefore: Thus saith the Lord God: I will make this proverb to cease, neither shall it be any more a common saying in Israel: and tell them that the days are at hand, and the effect of every vision.", "bbe": "For this cause say to them, This is what the Lord has said: I have made this saying come to an end, and it will no longer be used as a common saying in Israel; but say to them, The days are near, and the effect of every vision.", "geneva": "Tell them therefore, Thus sayeth the Lord God, I wil make this prouerbe to cease, and they shall no more vse it as a prouerbe in Israel: but say vnto them, The daies are at hand and the effect of euery vision.", "wycliffe": "Therfor seie thou to hem, The Lord God seith these thingis, Y schal make this prouerbe to ceesse, and it schal no more be seid comynli in Israel; and speke thou to hem, that the daies han neiyid, and ech word of profesie.", "rotherham": "Therefore say unto them, Thus, saith My Lord Yahweh, I will cause this proverb to cease, And they shall use it as a proverb no more in Israel,— But speak unto them, The days, are drawn near, And the substance of every vision.", "darby": "Tell them therefore, Thus saith the Lord Jehovah: I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say unto them, The days are at hand, and the accomplishment of every vision.", "twenty": "", "jps": "Tell them therefore: Thus saith the L-rd GOD: I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say unto them: The days are at hand, and the word of every vision.", "acv": "Tell them therefore, Thus says the lord Jehovah: I will make this proverb to cease, and they shall no more use it as a proverb in Israel, but say to them, The days are at hand, and the fulfillment of every vision.", "anderson": "", "haweis": "", "noyes": "Therefore say to them, Thus saith the Lord Jehovah: I will make this proverb to cease, and they shall no more use it as a proverb in Israel. But say to them, The days are at hand, and what is declared in every vision.", "webster": "Tell them therefore, Thus saith the Lord GOD: I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say to them, The days are at hand, and the effect of every vision.", "vulgate": "ideo dic ad eos haec dicit Dominus Deus quiescere faciam proverbium istud neque vulgo dicetur ultra in Israhel et loquere ad eos quod adpropinquaverint dies et sermo omnis visionis;", "brenton": "Therefore say to them, Thus saith the Lord; I will even set aside this parable, and the house of Israel shall no more at all use this parable: for thou shalt say to them, The days are at hand, and the import of every vision."}}, {"v": 24, "ref": "12:24", "o": "כִּ֠י לֹ֣א יִֽהְיֶ֥ה ע֛וֹד כָּל חֲז֥וֹן שָׁ֖וְא וּ/מִקְסַ֣ם חָלָ֑ק בְּ/ת֖וֹךְ בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "For there shall be no more any vain vision nor flattering divination within the house of Israel.", "web": "For there shall be no more any false vision nor flattering divination within the house of Israel.", "bsb": "For there will be no more false visions or flattering divinations within the house of Israel,", "asv": "For there shall be no more any false vision nor flattering divination within the house of Israel.", "ylt": "For there is no more any vain vision, and flattering divination, In the midst of the house of Israel.", "dra": "For there shall be no more any vain visions, nor doubtful divination in the midst of the children of Israel.", "bbe": "For there will be no more false visions or smooth use of secret arts in Israel.", "geneva": "For no vision shall be any more in vaine, neither shall there bee any flattering diuination within the house of Israel.", "wycliffe": "For whi ech visioun schal no more be voide, nether bifor tellyng of thing to comynge schal be douteful in the myddis of the sones of Israel;", "rotherham": "For there shall no more be— Any vision of falsehood Or divination of deceit, In the midst of the house of Israel.", "darby": "For there shall be no more any vain vision nor flattering divination in the midst of the house of Israel.", "twenty": "", "jps": "For there shall be no more any vain vision nor smooth divination within the house of Israel.", "acv": "For there shall no more be any false vision nor flattering divination within the house of Israel.", "anderson": "", "haweis": "", "noyes": "For there shall be no longer any vain vision or deceptive divination within the house of Israel.", "webster": "For there shall no more be any vain vision nor flattering divination within the house of Israel.", "vulgate": "non enim erit ultra omnis visio cassa neque divinatio ambigua in medio filiorum Israhel;", "brenton": "For there shall no more be any false vision, nor any one prophesying flatteries in the midst of the children of Israel."}}, {"v": 25, "ref": "12:25", "o": "כִּ֣י אֲנִ֣י יְהוָ֗ה אֲדַבֵּר֙ אֵת֩ אֲשֶׁ֨ר אֲדַבֵּ֤ר דָּבָר֙ וְ/יֵ֣עָשֶׂ֔ה לֹ֥א תִמָּשֵׁ֖ךְ ע֑וֹד כִּ֣י בִֽ/ימֵי/כֶ֞ם בֵּ֣ית הַ/מֶּ֗רִי אֲדַבֵּ֤ר דָּבָר֙ וַ/עֲשִׂיתִ֔י/ו נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "For I am the Lord: I will speak, and the word that I shall speak shall come to pass; it shall be no more prolonged: for in your days, O rebellious house, will I say the word, and will perform it, saith the Lord God.", "web": "For I am Yahweh; I will speak, and the word that I shall speak shall be performed; it shall be no more deferred: for in your days, rebellious house, will I speak the word, and will perform it, says the Lord Yahweh.", "bsb": "because I, the LORD, will speak whatever word I speak, and it will be fulfilled without delay. For in your days, O rebellious house, I will speak a message and bring it to pass, declares the Lord GOD.’”", "asv": "For I am Jehovah; I will speak, and the word that I shall speak shall be performed; it shall be no more deferred: for in your days, O rebellious house, will I speak the word, and will perform it, saith the Lord Jehovah.", "ylt": "For I am Jehovah, I speak, The word that I speak--it is done, It is not prolonged any more, For, in your days, O rebellious house, I speak a word, and I have done it, An affirmation of the Lord Jehovah.'", "dra": "For I the Lord will speak: and what word soever I shall speak, it shall come to pass, and shall not be prolonged any more: but in your days, ye provoking house, I will speak the word, and will do it, saith the Lord God.", "bbe": "For I am the Lord; I will say the word and what I say I will do; it will not be put off: for in your days, O uncontrolled people, I will say the word and do it, says the Lord.", "geneva": "For I am the Lord: I wil speake, and that thing that I shall speake, shall come to passe: it shall be no more prolonged: for in your dayes, O rebellious house, will I saye the thing, and will performe it, sayeth the Lord God.", "wycliffe": "for Y the Lord schal speke what euer word Y schal speke, and it schal be don; it schal no more be delaied, but in youre daies, ye hous terrynge to wraththe, Y schal speke a word, and Y schal do that word, seith the Lord God.", "rotherham": "For, I, Yahweh will speak whatsoever word I please to speak, And it shall be done, It shall not be delayed any more,— For in your own days, O perverse house, will I speak a word and perform it, Declareth My Lord. Yahweh.", "darby": "For I [am] Jehovah; I will speak, and the word that I shall speak shall be performed, it shall be no more deferred. For in your days, O rebellious house, will I speak the word and will perform it, saith the Lord Jehovah.", "twenty": "", "jps": "For I am HaShem; I will speak, what word soever it be that I shall speak, and it shall be performed; it shall be no more delayed; for in your days, O rebellious house, will I speak the word, and will perform it, saith the L-rd GOD.'", "acv": "For I am Jehovah. I will speak, and the word that I shall speak shall be performed. It shall be no more deferred. For in your days, O rebellious house, I will speak the word, and will perform it, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "For I am Jehovah; I speak, and the word which I speak shall come to pass; it shall no more be delayed. In your own days, ye rebellious house, will I speak the word and perform it, saith the Lord Jehovah.", "webster": "For I [am] the LORD: I will speak, and the word that I shall speak shall come to pass; it shall no more be prolonged: for in your days, O rebellious house, will I say the word, and will perform it, saith the Lord GOD.", "vulgate": "quia ego Dominus loquar quodcumque locutus fuero verbum et fiet non prolongabitur amplius sed in diebus vestris domus exasperans loquar verbum et faciam illud dicit Dominus Deus;", "brenton": "For I the Lord will speak my words; I will speak and perform them, and will no more delay, for in your days, O provoking house, I will speak the word, and will perform it, saith the Lord."}}, {"v": 26, "ref": "12:26", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Again the word of the Lord came to me, saying,", "web": "Again Yahweh’s word came to me, saying,", "bsb": "Furthermore, the word of the LORD came to me, saying,", "asv": "Again the word of Jehovah came to me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "Again the word of the Lord came to me, saying,", "geneva": "Againe the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide, Thou,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Again the word of HaShem came to me, saying:", "acv": "Again the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "Moreover the word of the Lord came to me, saying,"}}, {"v": 27, "ref": "12:27", "o": "בֶּן אָדָ֗ם הִנֵּ֤ה בֵֽית יִשְׂרָאֵל֙ אֹֽמְרִ֔ים הֶ/חָז֛וֹן אֲשֶׁר ה֥וּא חֹזֶ֖ה לְ/יָמִ֣ים רַבִּ֑ים וּ/לְ/עִתִּ֥ים רְחוֹק֖וֹת ה֥וּא נִבָּֽא", "en": {"kjv": "Son of man, behold, they of the house of Israel say, The vision that he seeth is for many days to come, and he prophesieth of the times that are far off.", "web": "Son of man, behold, they of the house of Israel say, The vision that he sees is for many day to come, and he prophesies of times that are far off.", "bsb": "“Son of man, take note that the house of Israel is saying, ‘The vision that he sees is for many years from now; he prophesies about the distant future.’", "asv": "Son of man, behold, they of the house of Israel say, The vision that he seeth is for many days to come, and he prophesieth of times that are far off.", "ylt": "`Son of man, lo, the house of Israel are saying, The vision that he is seeing is for many days, and of times far off he is prophesying,", "dra": "Son of man, behold the house of Israel, they that say: The visions that this man seeth, is for many days to come: and this man prophesieth of times afar off.", "bbe": "Son of man, see, the children of Israel say, The vision which he sees is for the days which are a long way off, and his words are of times still far away.", "geneva": "Sonne of man, beholde, they of the house of Israel say, The vision that hee seeth, is for many dayes to come, and he prophecieth of the times that are farre off.", "wycliffe": "sone of man, lo! the hous of Israel, of hem that seien, The visioun which this man seeth, is in to manye daies, and this man profesieth in to longe tymes.", "rotherham": "Son of man. Lo! the house of Israel are saying, the vision which he seeth is for many days, Yea for times far away, hath he prophesied.", "darby": "Son of man, behold, they of the house of Israel say, The vision that he seeth is for many days, and he prophesieth of times that are far off.", "twenty": "", "jps": "'Son of man, behold, they of the house of Israel say: The vision that he seeth is for many days to come, and he prophesieth of times that are far off.", "acv": "Son of man, behold, those of the house of Israel say, The vision that he sees is for many day to come, and he prophesies of times that are far off.", "anderson": "", "haweis": "", "noyes": "Son of man, behold, they of the house of Israel say, \"The vision which he seeth is for many days to come, and he prophesieth of times that are far off.\"", "webster": "Son of man, behold, [they of] the house of Israel say, The vision that he seeth [is] for many days [to come], and he prophesieth of the times [that are] distant.", "vulgate": "fili hominis ecce domus Israhel dicentium visio quam hic videt in dies multos et in tempora longa iste prophetat;", "brenton": "Son of man, behold, the provoking house of Israel boldly say, The vision which this man sees is for many days, and he prophesies for times afar off."}}, {"v": 28, "ref": "12:28", "o": "לָ/כֵ֞ן אֱמֹ֣ר אֲלֵי/הֶ֗ם כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה לֹא תִמָּשֵׁ֥ךְ ע֖וֹד כָּל דְּבָרָ֑/י אֲשֶׁ֨ר אֲדַבֵּ֤ר דָּבָר֙ וְ/יֵ֣עָשֶׂ֔ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Therefore say unto them, Thus saith the Lord God; There shall none of my words be prolonged any more, but the word which I have spoken shall be done, saith the Lord God.", "web": "Therefore tell them, Thus says the Lord Yahweh: None of my words shall be deferred any more, but the word which I shall speak shall be performed, says the Lord Yahweh.", "bsb": "Therefore tell them that this is what the Lord GOD says: ‘None of My words will be delayed any longer. The message I speak will be fulfilled, declares the Lord GOD.’”", "asv": "Therefore say unto them, Thus saith the Lord Jehovah: There shall none of my words be deferred any more, but the word which I shall speak shall be performed, saith the Lord Jehovah.", "ylt": "therefore say unto them: Thus said the Lord Jehovah: None of my words are prolonged any more, When I speak a word--it is done, An affirmation of the Lord Jehovah!'", "dra": "Therefore say to them: Thus saith the Lord God: not one word of mine shall be prolonged any more: the word that I shall speak shall be accomplished, saith the Lord God.", "bbe": "Say to them then, This is what the Lord has said: Not one of my words will be put off any longer, but what I say I will do, says the Lord.", "geneva": "Therefore say vnto them, Thus sayth the Lord God, All my wordes shall no longer be delayed, but that thing which I haue spoken, shall be done, saith the Lord God.", "wycliffe": "Therfor seie thou to hem, The Lord God seith these thingis, Ech word of me schal no more be deferrid; the word which Y schal speke, schal be fillid, seith the Lord God.", "rotherham": "Therefore say unto them. Thus saith My Lord Yahweh, None of my words shall be delayed any more,— Whatsoever word I speak, then shall it be performed, Declareth My Lord Yahweh.", "darby": "Therefore say unto them, Thus saith the Lord Jehovah: There shall none of my words be deferred any more, but the word that I have spoken shall be done, saith the Lord Jehovah.", "twenty": "", "jps": "Therefore say unto them: Thus saith the L-rd GOD: There shall none of My words be delayed any more, but the word which I shall speak shall be performed, saith the L-rd GOD.'", "acv": "Therefore say to them, Thus says the lord Jehovah: There shall none of my words be deferred any more, but the word which I shall speak shall be performed, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Therefore say to them, Thus saith the Lord Jehovah: There shall none of my words be deferred any more; what I speak shall be done, saith the Lord Jehovah.", "webster": "Therefore say to them, Thus saith the Lord GOD; There shall none of my words be further deferred, but the word which I have spoken shall be done, saith the Lord GOD.", "vulgate": "propterea dic ad eos haec dicit Dominus Deus non prolongabitur ultra omnis sermo meus verbum quod locutus fuero conplebitur dicit Dominus Deus;", "brenton": "Therefore say to them, Thus saith the Lord; Henceforth none of my words shall linger, which I shall speak: I will speak and do, saith the Lord."}}]}, {"c": 13, "verses": [{"v": 1, "ref": "13:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying:", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "13:2", "o": "בֶּן אָדָ֕ם הִנָּבֵ֛א אֶל נְבִיאֵ֥י יִשְׂרָאֵ֖ל הַ/נִּבָּאִ֑ים וְ/אָֽמַרְתָּ֙ לִ/נְבִיאֵ֣י מִ/לִּבָּ֔/ם שִׁמְע֖וּ דְּבַר יְהוָֽה", "en": {"kjv": "Son of man, prophesy against the prophets of Israel that prophesy, and say thou unto them that prophesy out of their own hearts, Hear ye the word of the Lord;", "web": "Son of man, prophesy against the prophets of Israel who prophesy, and say to those who prophesy out of their own heart, Hear Yahweh’s word:", "bsb": "“Son of man, prophesy against the prophets of Israel who are now prophesying. Tell those who prophesy out of their own imagination: Hear the word of the LORD!", "asv": "Son of man, prophesy against the prophets of Israel that prophesy, and say thou unto them that prophesy out of their own heart, Hear ye the word of Jehovah:", "ylt": "`Son of man, prophesy concerning the prophets of Israel who are prophesying, and thou hast said to those prophesying from their own heart: Hear ye a word of Jehovah:", "dra": "Son of man, prophesy thou against the prophets of Israel that prophesy: and thou shalt say to them that prophesy out of their own heart: Hear ye the word of the Lord:", "bbe": "Son of man, be a prophet against the prophets of Israel, and say to those prophets whose words are the invention of their hearts, Give ear to the word of the Lord;", "geneva": "Sonne of man, prophecie against the prophets of Israel, that prophecie, and say thou vnto them, that prophecie out of their owne hearts, Heare the worde of the Lord.", "wycliffe": "and he seide, Sone of man, profesie thou to the profetis of Israel that profesien; and thou schalt seie to hem that profesien of her herte,", "rotherham": "Son of man. prophesy against the prophets of Israel, who are prophesying,—and say unto them who prophesy out of their own heart, Hear ye the word of Yahweh,", "darby": "Son of man, prophesy against the prophets of Israel that prophesy, and say unto them that prophesy out of their own heart, Hear ye the word of Jehovah.", "twenty": "", "jps": "'Son of man, prophesy against the prophets of Israel that prophesy, and say thou unto them that prophesy out of their own heart: Hear ye the word of HaShem:", "acv": "Son of man, prophesy against the prophets of Israel who prophesy, and say thou to those who prophesy out of their own heart, Hear ye the word of Jehovah.", "anderson": "", "haweis": "", "noyes": "Son of man, prophesy against the prophets of Israel that prophesy, and say to them that prophesy out of their own hearts, Hear ye the word of Jehovah!", "webster": "Son of man, prophesy against the prophets of Israel that prophesy, and say thou to them that prophesy out of their own hearts, Hear ye the word of the LORD;", "vulgate": "fili hominis vaticinare ad prophetas Israhel qui prophetant et dices prophetantibus de corde suo audite verbum Domini;", "brenton": "Son of man, prophesy against the prophets of Israel, and thou shalt prophesy, and shalt say to them, Hear ye the word of the Lord:"}}, {"v": 3, "ref": "13:3", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה ה֖וֹי עַל הַ/נְּבִיאִ֣ים הַ/נְּבָלִ֑ים אֲשֶׁ֥ר הֹלְכִ֛ים אַחַ֥ר רוּחָ֖/ם וּ/לְ/בִלְתִּ֥י רָאֽוּ", "en": {"kjv": "Thus saith the Lord God; Woe unto the foolish prophets, that follow their own spirit, and have seen nothing!", "web": "Thus says the Lord Yahweh, Woe to the foolish prophets, who follow their own spirit, and have seen nothing!", "bsb": "This is what the Lord GOD says: Woe to the foolish prophets who follow their own spirit, yet have seen nothing.", "asv": "Thus saith the Lord Jehovah, Woe unto the foolish prophets, that follow their own spirit, and have seen nothing!", "ylt": "Thus said the Lord Jehovah: Woe unto the prophets who are foolish, Who are going after their own spirit, And they have seen nothing.", "dra": "Thus saith the Lord God: Woe to the foolish prophets that follow their own spirit, and see nothing.", "bbe": "This is what the Lord has said: A curse on the foolish prophets who go after the spirit which is in them and have seen nothing!", "geneva": "Thus sayth the Lord God, Woe vnto the foolish Prophets that follow their owne spirit, and haue seene nothing.", "wycliffe": "Here ye the word of the Lord. The Lord God seith these thingis, Wo to the vnwise profetis, that suen her spirit, and seen no thing;", "rotherham": "Thus, saith My Lord, Yahweh, Alas for the base prophets,—who follow their own spirit and have seen, nothing.", "darby": "Thus saith the Lord Jehovah: Woe unto the foolish prophets, that follow their own spirit, and have seen nothing!", "twenty": "", "jps": "Thus saith the L-rd GOD: Woe unto the vile prophets, that follow their own spirit, and things which they have not seen!", "acv": "Thus says the lord Jehovah: Woe to the foolish prophets, who follow their own spirit, and have seen nothing!", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Woe to the foolish prophets, that follow their own spirit, and have seen nothing!", "webster": "Thus saith the Lord GOD; Woe to the foolish prophets, that follow their own spirit, and have seen nothing!", "vulgate": "haec dicit Dominus Deus vae prophetis insipientibus qui sequuntur spiritum suum et nihil vident;", "brenton": "Thus saith the Lord, Woe to them that prophesy out of their own heart, and who see nothing at all."}}, {"v": 4, "ref": "13:4", "o": "כְּ/שֻׁעָלִ֖ים בָּ/חֳרָב֑וֹת נְבִיאֶ֥י/ךָ יִשְׂרָאֵ֖ל הָיֽוּ", "en": {"kjv": "O Israel, thy prophets are like the foxes in the deserts.", "web": "Israel, your prophets have been like foxes in the waste places.", "bsb": "Your prophets, O Israel, are like foxes among the ruins.", "asv": "O Israel, thy prophets have been like foxes in the waste places.", "ylt": "As foxes in the wastes, Thy prophets, O Israel, have been.", "dra": "Thy prophets, O Israel, were like foxes in the deserts.", "bbe": "O Israel, your prophets have been like jackals in the waste places.", "geneva": "O Israel, thy Prophets are like the foxes in the waste places.", "wycliffe": "Israel, thi profetis weren as foxis in desert.", "rotherham": "As jackals, among ruins, thy prophets O Israel have been.", "darby": "O Israel, thy prophets have been like foxes in desert places.", "twenty": "", "jps": "O Israel, thy prophets have been like foxes in ruins.", "acv": "O Israel, thy prophets have been like foxes in the waste places.", "anderson": "", "haweis": "", "noyes": "Thy prophets, O Israel, are like the foxes in the deserts.", "webster": "O Israel, thy prophets are like the foxes in the deserts.", "vulgate": "quasi vulpes in desertis prophetae tui Israhel erant;", "brenton": "Thy prophets, O Israel, are like foxes in the deserts."}}, {"v": 5, "ref": "13:5", "o": "לֹ֤א עֲלִיתֶם֙ בַּ/פְּרָצ֔וֹת וַ/תִּגְדְּר֥וּ גָדֵ֖ר עַל בֵּ֣ית יִשְׂרָאֵ֑ל לַ/עֲמֹ֥ד בַּ/מִּלְחָמָ֖ה בְּ/י֥וֹם יְהוָֽה", "en": {"kjv": "Ye have not gone up into the gaps, neither made up the hedge for the house of Israel to stand in the battle in the day of the Lord.", "web": "You have not gone up into the gaps, neither built up the wall for the house of Israel, to stand in the battle in the day of Yahweh.", "bsb": "You did not go up to the gaps or restore the wall around the house of Israel so that it would stand in the battle on the Day of the LORD.", "asv": "Ye have not gone up into the gaps, neither built up the wall for the house of Israel, to stand in the battle in the day of Jehovah.", "ylt": "Ye have not gone up into breaches, Nor do ye make a fence for the house of Israel, To stand in battle in a day of Jehovah.", "dra": "You have not gone up to face the enemy, nor have you set up a wall for the house of Israel, to stand in battle in the day of the Lord.", "bbe": "You have not gone up into the broken places or made up the wall for the children of Israel to take your place in the fight in the day of the Lord.", "geneva": "Ye haue not risen vp in the gappes, neither made vp the hedge for ye house of Israel, to stand in the battel in the daye of the Lord.", "wycliffe": "Ye stieden not euene ayens, nether ayensettiden a wal for the hous of Israel, that ye shulden stonde in batel in the dai of the Lord.", "rotherham": "Ye have not gone up into the breaches, Nor built a wall about the house of Israel,- to stand in the battle in the day of Yahweh.", "darby": "Ye have not gone up into the breaches, nor made up the fence for the house of Israel, to stand in the battle in the day of Jehovah.", "twenty": "", "jps": "Ye have not gone up into the breaches, neither made up the hedge for the house of Israel, to stand in the battle in the day of HaShem.", "acv": "Ye have not gone up into the gaps, nor built up the wall for the house of Israel to stand in the battle in the day of Jehovah.", "anderson": "", "haweis": "", "noyes": "Ye have not gone up into the breaches, nor built a wall around the house of Israel, to stand in battle in the day of Jehovah.", "webster": "Ye have not gone up into the gaps, neither made up the hedge for the house of Israel to stand in the battle in the day of the LORD.", "vulgate": "non ascendistis ex adverso neque opposuistis murum pro domo Israhel ut staretis in proelio in die Domini;", "brenton": "They have not continued steadfast, and they have gathered flocks against the house of Israel, they that say,"}}, {"v": 6, "ref": "13:6", "o": "חָ֤זוּ שָׁוְא֙ וְ/קֶ֣סֶם כָּזָ֔ב הָ/אֹֽמְרִים֙ נְאֻם יְהוָ֔ה וַֽ/יהוָ֖ה לֹ֣א שְׁלָחָ֑/ם וְ/יִֽחֲל֖וּ לְ/קַיֵּ֥ם דָּבָֽר", "en": {"kjv": "They have seen vanity and lying divination, saying, The Lord saith: and the Lord hath not sent them: and they have made others to hope that they would confirm the word.", "web": "They have seen falsehood and lying divination, who say, Yahweh says; but Yahweh has not sent them: and they have made men to hope that the word would be confirmed.", "bsb": "They see false visions and speak lying divinations. They claim, ‘Thus declares the LORD,’ when the LORD did not send them; yet they wait for the fulfillment of their message.", "asv": "They have seen falsehood and lying divination, that say, Jehovah saith; but Jehovah hath not sent them: and they have made men to hope that the word would be confirmed.", "ylt": "They have seen vanity, and lying divination, Who are saying: An affirmation of Jehovah, And Jehovah hath not sent them, And they have hoped to establish a word.", "dra": "They see vain things, and they foretell lies, saying: The Lord saith: whereas the Lord hath not sent them: and they have persisted to confirm what they have said.", "bbe": "They have seen visions without substance and made use of secret arts, who say, The Lord has said; and the Lord has not sent them: hoping that the word would have effect.", "geneva": "They haue seene vanitie, and lying diuination, saying, The Lord sayth it, and the Lord hath not sent them: and they haue made others to hope that they would cofirme the word of their prophecie.", "wycliffe": "Thei seen veyn thingis, and deuynen a leesyng, and seien, The Lord seith, whanne the Lord sente not hem; and thei contynueden to conferme the word.", "rotherham": "They have had Visions of falsehood, and Divinations of lies, Who say. Declareth Yahweh, when, Yahweh, hath not sent them,— Yet have they waited for a fulfilling of the word.", "darby": "They have seen vanity and lying divination, that say, Jehovah saith! and Jehovah hath not sent them; and they make [them] to hope that the word will be fulfilled.", "twenty": "", "jps": "They have seen vanity and lying divination, that say: HaShem saith; and HaShem hath not sent them, yet they hope that the word would be confirmed!", "acv": "They have seen falsehood and lying divination, who say, Jehovah says, but Jehovah has not sent them. And they have made men to hope that the word would be confirmed.", "anderson": "", "haweis": "", "noyes": "They see falsehood, and lying divination. They say, \"Jehovah hath spoken,\" when Jehovah hath not sent them; and they cause men to hope for the fulfilment of the word.", "webster": "They have seen vanity and lying divination, saying, The LORD saith: and the LORD hath not sent them: and they have made [others] to hope that they would confirm the word.", "vulgate": "vident vana et divinant mendacium dicentes ait Dominus cum Dominus non miserit eos et perseveraverunt confirmare sermonem;", "brenton": "In the day of the Lord, have not stood, seeing false visions, prophesying vanities, who say, The Lord saith, and the Lord has not sent them, and they began to try to confirm the word."}}, {"v": 7, "ref": "13:7", "o": "הֲ/ל֤וֹא מַֽחֲזֵה שָׁוְא֙ חֲזִיתֶ֔ם וּ/מִקְסַ֥ם כָּזָ֖ב אֲמַרְתֶּ֑ם וְ/אֹֽמְרִים֙ נְאֻם יְהוָ֔ה וַ/אֲנִ֖י לֹ֥א דִבַּֽרְתִּי", "en": {"kjv": "Have ye not seen a vain vision, and have ye not spoken a lying divination, whereas ye say, The Lord saith it; albeit I have not spoken?", "web": "Haven’t you seen a false vision, and haven’t you spoken a lying divination, in that you say, Yahweh says; but I have not spoken?", "bsb": "Haven’t you seen a false vision and spoken a lying divination when you proclaim, ‘Thus declares the LORD,’ even though I have not spoken?", "asv": "Have ye not seen a false vision, and have ye not spoken a lying divination, in that ye say, Jehovah saith; albeit I have not spoken?", "ylt": "A vain vision have ye not seen, And a lying divination spoken, When ye say: An affirmation of Jehovah, And I have not spoken?", "dra": "Have you not seen a vain vision and spoken a lying divination: and you say: The Lord saith: whereas I have not spoken.", "bbe": "Have you not seen a vision without substance and have you not falsely made use of secret arts, when you say, The Lord has said; though I have said nothing?", "geneva": "Haue ye not seene a vaine vision? and haue yee not spoken a lying diuination? ye say, The Lord sayth it, albeit I haue not spoken.", "wycliffe": "Whether ye seen not a veyn visioun, and spaken fals diuynyng, and seiden, The Lord seith, whanne Y spak not?", "rotherham": "Is it not a Vision of falsehood, ye have seen, and a Divination of lies, ye have spoken, Since ye are saying. Declareth Yahweh! when I have not spoken?", "darby": "Have ye not seen a vain vision, and spoken a lying divination, when ye say, Jehovah saith; and I have not spoken?", "twenty": "", "jps": "Have ye not seen a vain vision, and have ye not spoken a lying divination, whereas ye say: HaShem saith; albeit I have not spoken?", "acv": "Have ye not seen a false vision, and have ye not spoken a lying divination, in that ye say, Jehovah says, albeit I have not spoken?", "anderson": "", "haweis": "", "noyes": "Have ye not seen a false vision, and have ye not spoken a lying divination, and said, \"Jehovah hath spoken,\" when I have not spoken?", "webster": "Have ye not seen a vain vision, and have ye not spoken a lying divination, whereas ye say, The LORD saith [it], although I have not spoken?", "vulgate": "numquid non visionem cassam vidistis et divinationem mendacem locuti estis et dicitis ait Dominus cum ego non sim locutus;", "brenton": "Have ye not seen a false vision? and spoken vain prophecies?"}}, {"v": 8, "ref": "13:8", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֚עַן דַּבֶּרְ/כֶ֣ם שָׁ֔וְא וַ/חֲזִיתֶ֖ם כָּזָ֑ב לָ/כֵן֙ הִנְ/נִ֣י אֲלֵי/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Therefore thus saith the Lord God; Because ye have spoken vanity, and seen lies, therefore, behold, I am against you, saith the Lord God.", "web": "Therefore thus says the Lord Yahweh: Because you have spoken falsehood, and seen lies, therefore, behold, I am against you, says the Lord Yahweh.", "bsb": "Therefore this is what the Lord GOD says: Because you have uttered vain words and seen false visions, I am against you, declares the Lord GOD.", "asv": "Therefore thus saith the Lord Jehovah: Because ye have spoken falsehood, and seen lies, therefore, behold, I am against you, saith the Lord Jehovah.", "ylt": "Therefore, thus said the Lord Jehovah: Because ye have spoken vanity, and seen a lie, Therefore, lo, I am against you, An affirmation of the Lord Jehovah.", "dra": "Therefore thus saith the Lord God: Because you have spoken vain things, and have seen lies: therefore behold I come against you, saith the Lord God.", "bbe": "So this is what the Lord has said: Because your words are without substance and your visions are false, see, I am against you, says the Lord.", "geneva": "Therefore thus sayth the Lord God, Because ye haue spoken vanytie and haue seene lyes, therefore beholde, I am agaynst you, sayth the Lord God,", "wycliffe": "Therfor the Lord God seith these thingis, For ye spaken veyn thingis, and sien a leesyng, therfor lo! Y to you, seith the Lord God.", "rotherham": "Therefore Thus saith My Lord Yahweh, Because ye have spoken falsehood, And have had visions of lies, Therefore behold me! against you, Declareth My Lord Yahweh.", "darby": "Therefore thus saith the Lord Jehovah: Because ye speak vanity, and have seen lies, therefore behold, I am against you, saith the Lord Jehovah.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because ye have spoken vanity, and seen lies, therefore, behold, I am against you, saith the L-rd GOD.", "acv": "Therefore thus says the lord Jehovah: Because ye have spoken falsehood, and seen lies, therefore, behold, I am against you, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because ye have spoken falsehood and have seen a lie, therefore, behold, I am against you, saith the Lord Jehovah.", "webster": "Therefore thus saith the Lord GOD; Because ye have spoken vanity, and seen lies, therefore, behold, I [am] against you, saith the Lord GOD.", "vulgate": "propterea haec dicit Dominus Deus quia locuti estis vana et vidistis mendacium ideo ecce ego ad vos ait Dominus Deus;", "brenton": "And therefore say, Thus saith the Lord; Because your words are false, and your prophecies are vain, therefore, behold, I am against you, saith the Lord."}}, {"v": 9, "ref": "13:9", "o": "וְ/הָיְתָ֣ה יָדִ֗/י אֶֽל הַ/נְּבִיאִ֞ים הַ/חֹזִ֣ים שָׁוְא֮ וְ/הַ/קֹּסְמִ֣ים כָּזָב֒ בְּ/ס֧וֹד עַמִּ֣/י לֹֽא יִהְי֗וּ וּ/בִ/כְתָ֤ב בֵּֽית יִשְׂרָאֵל֙ לֹ֣א יִכָּתֵ֔בוּ וְ/אֶל אַדְמַ֥ת יִשְׂרָאֵ֖ל לֹ֣א יָבֹ֑אוּ וִ/ידַעְתֶּ֕ם כִּ֥י אֲנִ֖י אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And mine hand shall be upon the prophets that see vanity, and that divine lies: they shall not be in the assembly of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel; and ye shall know that I am the Lord God.", "web": "My hand shall be against the prophets who see false visions, and who divine lies: they shall not be in the council of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel; and you shall know that I am the Lord Yahweh.", "bsb": "My hand will be against the prophets who see false visions and speak lying divinations. They will not belong to the council of My people or be recorded in the register of the house of Israel, nor will they enter the land of Israel. Then you will know that I am the Lord GOD.", "asv": "And my hand shall be against the prophets that see false visions, and that divine lies: they shall not be in the council of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel; and ye shall know that I am the Lord Jehovah.", "ylt": "And My hand hath been on the prophets, Who are seeing vanity, and who are divining a lie, In the assembly of My people they are not, And in the writing of the house of Israel they are not written, And unto the ground of Israel they come not, And ye have known that I am the Lord Jehovah.", "dra": "And my hand shall be upon the prophets that see vain things, and that divine lies: they shall not be in the council of my people, nor shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel, and you shall know that I am the Lord God.", "bbe": "And my hand will be against the prophets who see visions without substance and who make false use of secret arts: they will not be in the secret of my people, and they will not be recorded in the list of the children of Israel, and they will not come into the land of Israel; and it will be clear to you that I am the Lord.", "geneva": "And mine hande shalbe vpon the Prophets that see vanity, and diuine lies: they shall not be in the assemblie of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel: and yee shall know that I am the Lord God.", "wycliffe": "And myn hond schal be on the profetis that seen veyn thingis, and dyuynen a leesyng; thei schulen not be in the councel of my puple, and thei schulen not be writun in the scripture of the hous of Israel, nether thei schulen entre in to the lond of Israel; and ye schulen wite, that Y am the Lord God.", "rotherham": "So then my hand shall be against the prophets who have Visions of falsehood and who divine Divinations of lies— In the council of my people, shall they not be found. And in the register of the house of Israel, shall they not be written, And Upon the so of Israel, shall they not enter,— So shall ye know that, I, am The Lord Yahweh,", "darby": "And my hand shall be against the prophets that see vanity and that divine lies: they shall not be in the council of my people, neither shall they be written in the register of the house of Israel, and they shall not enter into the land of Israel: and ye shall know that I [am] the Lord Jehovah.", "twenty": "", "jps": "And My hand shall be against the prophets that see vanity, and that divine lies; they shall not be in the council of My people, neither shall they be written in the register of the house of Israel, neither shall they enter into the land of Israel; and ye shall know that I am the L-rd GOD.", "acv": "And my hand shall be against the prophets who see false visions, and who divine lies. They shall not be in the council of my people, nor shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel. And ye shall know that I am the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "My hand shall be against the prophets that see falsehood and divine lies. They shall not be in the assembly of my people, neither shall they be written in the register of the house of Israel, neither shall they enter into the land of Israel: and ye shall know that I am the Lord Jehovah.", "webster": "And my hand shall be upon the prophets that see vanity, and that divine lies: they shall not be in the assembly of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel; and ye shall know that I [am] the Lord GOD.", "vulgate": "et erit manus mea super prophetas qui vident vana et divinant mendacium in concilio populi mei non erunt et in scriptura domus Israhel non scribentur nec in terra Israhel ingredientur et scietis quia ego Dominus Deus;", "brenton": "And I will stretch forth my hand against the prophets that see false visions, and those that utter vanities: they shall not partake of the instruction of my people, neither shall they be written in the roll of the house of Israel, and they shall not enter into the land of Israel; and they shall know that I am the Lord."}}, {"v": 10, "ref": "13:10", "o": "יַ֣עַן וּ/בְ/יַ֜עַן הִטְע֧וּ אֶת עַמִּ֛/י לֵ/אמֹ֥ר שָׁל֖וֹם וְ/אֵ֣ין שָׁל֑וֹם וְ/הוּא֙ בֹּ֣נֶה חַ֔יִץ וְ/הִנָּ֛/ם טָחִ֥ים אֹת֖/וֹ תָּפֵֽל", "en": {"kjv": "Because, even because they have seduced my people, saying, Peace; and there was no peace; and one built up a wall, and, lo, others daubed it with untempered morter:", "web": "Because, even because they have seduced my people, saying, Peace; and there is no peace; and when one builds up a wall, behold, they plaster it with whitewash:", "bsb": "Because they have led My people astray, saying, ‘Peace,’ when there is no peace, and whitewashing any flimsy wall that is built,", "asv": "Because, even because they have seduced my people, saying, Peace; and there is no peace; and when one buildeth up a wall, behold, they daub it with untempered mortar:", "ylt": "Because, even because, they did cause My people to err, Saying, Peace! and there is no peace, And that one is building a wall, And lo, they are daubing it with chalk.", "dra": "Because they have deceived my people, saying: Peace, and there is no peace: and the people built up a wall, and they daubed it with dirt without straw.", "bbe": "Because, even because they have been guiding my people into error, saying, Peace; when there is no peace; and in the building of a division wall they put whitewash on it:", "geneva": "And therefore, because they haue deceiued my people, saying, Peace, and there was no peace: and one buylt vp a wall, and behold, the others daubed it with vntempered morter,", "wycliffe": "For thei disseyueden my puple, and seiden, Pees, pees, and no pees is; and it bildide a wal, but thei pargitiden it with fen with out chaffis.", "rotherham": "Because, yea, even because, they have led astray my people saying. Prosperity! when there was no prosperity,—and one man, was building a partition wall, when there they were! eating it with whitewash", "darby": "Because, yea because they have seduced my people, saying, Peace! and there is no peace; and one buildeth up a wall, and lo, they daub it with untempered [mortar] —", "twenty": "", "jps": "Because, even because they have led My people astray, saying: Peace, and there is no peace; and when it buildeth up a slight wall, behold, they daub it with whited plaster;", "acv": "Because, even because they have seduced my people, saying, Peace, and there is no peace, and when a man builds up a wall, behold, they daub it with untempered mortar,", "anderson": "", "haweis": "", "noyes": "Because, yea, because they seduce my people, and say, \"Peace!\" when there is no peace; and one buildeth up a wall, and, behold, they daub it with untempered mortar;", "webster": "Because, even because they have seduced my people, saying, Peace; and [there was] no peace; and one built up a wall, and lo, others daubed it with untempered [mortar]:", "vulgate": "eo quod deceperint populum meum dicentes pax et non est pax et ipse aedificabat parietem illi autem liniebant eum luto absque paleis;", "brenton": "Because they have caused my people to err, saying, Peace; and there is no peace; and one builds a wall, and they plaster it, —it shall fall."}}, {"v": 11, "ref": "13:11", "o": "אֱמֹ֛ר אֶל טָחֵ֥י תָפֵ֖ל וְ/יִפֹּ֑ל הָיָ֣ה גֶּ֣שֶׁם שׁוֹטֵ֗ף וְ/אַתֵּ֜נָה אַבְנֵ֤י אֶלְגָּבִישׁ֙ תִּפֹּ֔לְנָה וְ/ר֥וּחַ סְעָר֖וֹת תְּבַקֵּֽעַ", "en": {"kjv": "Say unto them which daub it with untempered morter, that it shall fall: there shall be an overflowing shower; and ye, O great hailstones, shall fall; and a stormy wind shall rend it.", "web": "tell those who plaster it with whitewash, that it shall fall: there shall be an overflowing shower; and you, great hailstones, shall fall; and a stormy wind shall tear it.", "bsb": "tell those whitewashing the wall that it will fall. Rain will come in torrents, I will send hailstones plunging down, and a windstorm will burst forth.", "asv": "say unto them that daub it with untempered mortar, that it shall fall: there shall be an overflowing shower; and ye, O great hailstones, shall fall; and a stormy wind shall rend it.", "ylt": "Say to those daubing with chalk--It falleth, There hath been an overflowing shower, And ye, O hailstones, do fall, And a tempestuous wind doth rend,", "dra": "Say to them that daub without tempering, that it shall fall: for there shall be an overflowing shower, and I will cause great hailstones to fall violently from above, and a stormy wind to throw it down.", "bbe": "Say to those who put whitewash on it, There will be an overflowing shower; and you, O ice-drops, will come raining down; and it will be broken in two by the storm-wind.", "geneva": "Say vnto them which daube it with vntempered morter, that it shall fall: for there shall come a great showre, and I wil sende haylestones, which shall cause it to fall, and a stormie winde shall breake it.", "wycliffe": "Seie thou to hem that pargiten with out temperure, that it schal falle doun; for a strong reyn schal be flowynge, and I shal yyue ful grete stoones fallinge fro aboue, and Y schal yyue a wynd of tempest that distrieth.", "rotherham": "Say thou unto them who are coating with whitewash It shall fall,- There hath come an overflowing rain And I will make hail-stones fall, And a tempestuous wind shall break it down.", "darby": "say unto them which daub it with untempered [mortar] that it shall fall: there shall be an overflowing rain, and ye, O great hailstones, shall fall, and a stormy wind shall burst forth.", "twenty": "", "jps": "say unto them that daub it with whited plaster, that it shall fall; there shall be an overflowing shower, and ye, O great hailstones, shall fall, and a stormy wind shall break forth,", "acv": "say to those who daub it with untempered mortar, that it shall fall. There shall be an overflowing shower, and ye, O great hailstones, shall fall, and a stormy wind shall rend it.", "anderson": "", "haweis": "", "noyes": "say to them which daub it with untempered mortar, that it shall fall; there shall be an overflowing shower, and ye, O great hailstones, shall fall, and a stormy wind shall rend it.", "webster": "Say to them who daub [it] with untempered [mortar], that it shall fall: there shall be an overflowing shower; and ye, O great hailstones, shall fall; and a stormy wind shall rend [it].", "vulgate": "dic ad eos qui liniunt absque temperatura quod casurus sit erit enim imber inundans et dabo lapides praegrandes desuper inruentes et ventum procellae dissipantem;", "brenton": "Say to them that plaster it, It shall fall; and there shall be a flooding rain; and I will send great stones upon their joinings, and they shall fall; and there shall be a sweeping wind, and it shall be broken."}}, {"v": 12, "ref": "13:12", "o": "וְ/הִנֵּ֖ה נָפַ֣ל הַ/קִּ֑יר הֲ/לוֹא֙ יֵאָמֵ֣ר אֲלֵי/כֶ֔ם אַיֵּ֥ה הַ/טִּ֖יחַ אֲשֶׁ֥ר טַחְתֶּֽם", "en": {"kjv": "Lo, when the wall is fallen, shall it not be said unto you, Where is the daubing wherewith ye have daubed it?", "web": "Behold, when the wall has fallen, shall it not be said to you, Where is the plaster with which you have plastered it?", "bsb": "Surely when the wall has fallen, you will not be asked, ‘Where is the whitewash with which you covered it?’", "asv": "Lo, when the wall is fallen, shall it not be said unto you, Where is the daubing wherewith ye have daubed it?", "ylt": "And lo, fallen hath the wall! Doth not one say unto you, Where is the daubing that ye daubed?", "dra": "Behold, when the wall is fallen: shall it not be said to you: Where is the daubing wherewith you have daubed it?", "bbe": "And when the wall has come down, will they not say to you, Where is the whitewash which you put on it?", "geneva": "Lo, when the wall is fallen, shall it not bee sayd vnto you, Where is the daubing wherewith ye haue daubed it?", "wycliffe": "For lo! the wal felle doun. Whether it schal not be seid to you, Where is the pargetyng, which ye pargetiden?", "rotherham": "Lo! when the wall hath fallen, shall it not be said unto you, Where is the coating, wherewith ye coated it?", "darby": "And lo, when the wall is fallen, shall it not be said unto you, Where is the daubing with which ye have daubed [it]?", "twenty": "", "jps": "and, lo, when the wall is fallen, shall it not be said unto you: Where is the daubing wherewith ye have daubed it?", "acv": "Lo, when the wall has fallen, shall it not be said to you, Where is the daubing with which ye have daubed it?", "anderson": "", "haweis": "", "noyes": "So when the wall is fallen, shall not men say to you, \"Where is the daubing wherewith ye have daubed it?\"", "webster": "Lo, when the wall hath fallen, shall it not be said to you, Where [is] the daubing with which ye have daubed [it]?", "vulgate": "siquidem ecce cecidit paries numquid non dicetur vobis ubi est litura quam levistis;", "brenton": "And lo! the wall has fallen; and will they not say to you, Where is your plaster wherewith ye plastered it?"}}, {"v": 13, "ref": "13:13", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה וּ/בִקַּעְתִּ֥י רֽוּחַ סְעָר֖וֹת בַּֽ/חֲמָתִ֑/י וְ/גֶ֤שֶׁם שֹׁטֵף֙ בְּ/אַפִּ֣/י יִֽהְיֶ֔ה וְ/אַבְנֵ֥י אֶלְגָּבִ֖ישׁ בְּ/חֵמָ֥ה לְ/כָלָֽה", "en": {"kjv": "Therefore thus saith the Lord God; I will even rend it with a stormy wind in my fury; and there shall be an overflowing shower in mine anger, and great hailstones in my fury to consume it.", "web": "Therefore thus says the Lord Yahweh: I will even tear it with a stormy wind in my wrath; and there shall be an overflowing shower in my anger, and great hailstones in wrath to consume it.", "bsb": "Therefore this is what the Lord GOD says: In My wrath I will release a windstorm, and in My anger torrents of rain and hail will fall with destructive fury.", "asv": "Therefore thus saith the Lord Jehovah: I will even rend it with a stormy wind in my wrath; and there shall be an overflowing shower in mine anger, and great hailstones in wrath to consume it.", "ylt": "Therefore, thus said the Lord Jehovah: I have rent with a tempestuous wind in My fury, And an overflowing shower is in Mine anger, And hailstones in My fury--to consume.", "dra": "Therefore thus saith the Lord God: Lo, I will cause a stormy wind to break forth in my indignation, and there shall be an overflowing shower in my anger: and great hailstones in my wrath to consume.", "bbe": "For this reason, the Lord has said: I will have it broken in two by a storm-wind in my passion; and there will be an overflowing shower in my wrath, and you, O ice-drops, will come raining angrily down.", "geneva": "Therefore thus sayth the Lord God, I will cause a stormie winde to breake foorth in my wrath, and a great showre shall bee in mine anger, and hailestones in mine indignation to consume it.", "wycliffe": "Therfor the Lord God seith these thingis, And Y schal make the spirit of tempestis to breke out in myn indignacioun, and strong reyn flowynge in my strong veniaunce schal be, and greet stoonys in wraththe in to wastyng.", "rotherham": "Therefore Thus saith my Lord, Yahweh, So will I break down with a tempestuous wind. in mine indignation,— And an overflowing rain in mine anger, shall there be, With hailstones in wrath to make an end;", "darby": "Therefore thus saith the Lord Jehovah: I will cause to burst forth a stormy wind in my fury; and there shall be an overflowing rain in mine anger, and hail-stones in fury for utter destruction.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: I will even cause a stormy wind to break forth in My fury; and there shall be an overflowing shower in Mine anger, and great hailstones in fury to consume it.", "acv": "Therefore thus says the lord Jehovah: I will even rend it with a stormy wind in my wrath, and there shall be an overflowing shower in my anger, and great hailstones in wrath to consume it.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: I will even rend it with a stormy wind in my fury, and there shall be an overflowing shower in mine anger, and great hailstones in my fury to consume it.", "webster": "Therefore thus saith the Lord GOD; I will even rend [it] with a stormy wind in my fury; and there shall be an overflowing shower in my anger, and great hailstones in [my] fury to consume [it].", "vulgate": "propterea haec dicit Dominus Deus et erumpere faciam spiritum tempestatum in indignatione mea et imber inundans in furore meo erit et lapides grandes in ira in consummationem;", "brenton": "Therefore thus saith the Lord; I will even cause to burst forth a sweeping blast with fury, and there shall be a flooding rain in my wrath; and in my fury I will bring on great stones for complete destruction."}}, {"v": 14, "ref": "13:14", "o": "וְ/הָ֨רַסְתִּ֜י אֶת הַ/קִּ֨יר אֲשֶׁר טַחְתֶּ֥ם תָּפֵ֛ל וְ/הִגַּעְתִּ֥י/הוּ אֶל הָ/אָ֖רֶץ וְ/נִגְלָ֣ה יְסֹד֑/וֹ וְ/נָֽפְלָה֙ וּ/כְלִיתֶ֣ם בְּ/תוֹכָ֔/הּ וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "So will I break down the wall that ye have daubed with untempered morter, and bring it down to the ground, so that the foundation thereof shall be discovered, and it shall fall, and ye shall be consumed in the midst thereof: and ye shall know that I am the Lord.", "web": "So will I break down the wall that you have plastered with whitewash, and bring it down to the ground, so that its foundation shall be uncovered; and it shall fall, and you shall be consumed in its midst: and you shall know that I am Yahweh.", "bsb": "I will tear down the wall you whitewashed and level it to the ground, so that its foundation is exposed. The city will fall, and you will be destroyed within it. Then you will know that I am the LORD.", "asv": "So will I break down the wall that ye have daubed with untempered mortar, and bring it down to the ground, so that the foundation thereof shall be uncovered; and it shall fall, and ye shall be consumed in the midst thereof: and ye shall know that I am Jehovah.", "ylt": "And I have broken down the wall that ye daubed with chalk, And have caused it to come unto the earth, And revealed hath been its foundation, And it hath fallen, And ye have been consumed in its midst, And ye have known that I am Jehovah.", "dra": "And I will break down the wall that you have daubed with untempered mortar: and I will make it even with the ground, and the foundation thereof shall be laid bare: and it shall fall, and shall be consumed in the midst thereof: and you shall know that I am the Lord.", "bbe": "So I will let the wall, which you were covering with whitewash, be broken down; I will have it levelled to the earth so that its base is uncovered: it will come down, and destruction will come on you with it; and it will be clear to you that I am the Lord.", "geneva": "So I wil destroy the wall that ye haue daubed with vntempered morter, and bring it downe to the ground, so that the fundation thereof shalbe discouered, and it shall fal, and ye shalbe consumed in the middes thereof, and ye shall know, that I am the Lord.", "wycliffe": "And Y schal distrie the wal, which ye pargetiden with out temperure, and Y schal make it euene with the erthe; and the foundement therof schal be schewid, and it schal falle doun, and it schal be wastid in the myddis therof; and ye schulen wite, that Y am the Lord.", "rotherham": "And I will pull down the wall which ye have coated with whitewash And will bring it unto the ground So shall be discovered its foundation, Yea it shall fall And ye shall come to an end in the midst thereof, So shall ye know that, I, am Yahweh.", "darby": "And I will break down the wall that ye have daubed with untempered [mortar], and bring it down to the ground, so that the foundation thereof shall be discovered; and it shall fall, and ye shall be destroyed in the midst thereof; and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "So will I break down the wall that ye have daubed with whited plaster, and bring it down to the ground, so that the foundation thereof shall be uncovered; and it shall fall, and ye shall be consumed in the midst thereof; and ye shall know that I am HaShem.", "acv": "So I will break down the wall that ye have daubed with untempered mortar, and bring it down to the ground, so that the foundation thereof shall be uncovered. And it shall fall, and ye shall be consumed in the midst of it. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus I will break down the wall which ye have daubed with untempered mortar, and will bring it down to the ground, so that the foundation thereof shall be discovered; it shall fall, and ye shall be consumed in the midst thereof, that ye may know that I am Jehovah.", "webster": "So will I break down the wall that ye have daubed with untempered [mortar], and bring it down to the ground, so that its foundation shall be made bare, and it shall fall, and ye shall be consumed in the midst of it: and ye shall know that I [am] the LORD.", "vulgate": "et destruam parietem quem levistis absque temperamento et adaequabo eum terrae et revelabitur fundamentum eius et cadet et consumetur in medio eius et scietis quia ego sum Dominus;", "brenton": "And I will break down the wall which ye have plastered, and it shall fall; and I will lay it on the ground, and its foundations shall be discovered, and it shall fall; and ye shall be consumed with rebukes: and ye shall know that I am the Lord."}}, {"v": 15, "ref": "13:15", "o": "וְ/כִלֵּיתִ֤י אֶת חֲמָתִ/י֙ בַּ/קִּ֔יר וּ/בַ/טָּחִ֥ים אֹת֖/וֹ תָּפֵ֑ל וְ/אֹמַ֤ר לָ/כֶם֙ אֵ֣ין הַ/קִּ֔יר וְ/אֵ֖ין הַ/טָּחִ֥ים אֹתֽ/וֹ", "en": {"kjv": "Thus will I accomplish my wrath upon the wall, and upon them that have daubed it with untempered morter, and will say unto you, The wall is no more, neither they that daubed it;", "web": "Thus will I accomplish my wrath on the wall, and on those who have plastered it with whitewash; and I will tell you, The wall is no more, neither those who plastered it;", "bsb": "And after I have vented My wrath against the wall and against those who whitewashed it, I will say to you: ‘The wall is gone, and so are those who whitewashed it—", "asv": "Thus will I accomplish my wrath upon the wall, and upon them that have daubed it with untempered mortar; and I will say unto you, The wall is no more, neither they that daubed it;", "ylt": "And I have completed My wrath on the wall, And on those daubing it with chalk, And I say to you: The wall is not, And those daubing it are not;", "dra": "And I will accomplish my wrath upon the wall, and upon them that daub it without tempering the mortar, and I will say to you: The wall is no more, and they that daub it are no more.", "bbe": "So I will let loose my passion on the wall in full measure, and on those who put whitewash on it; and I will say to you, Where is the wall, and where are those who put whitewash on it?", "geneva": "Thus will I accomplish my wrath vpon the wall, and vpon them that haue daubed it with vntempered morter, and will say vnto you, The wall is no more, neither the daubers thereof,", "wycliffe": "And Y schal fille myn indignacioun in the wal, and in hem that pargeten it with out temperure; and Y schal seie to you, The wal is not, and thei ben not,", "rotherham": "Thus will I bring to an end mine indignation against the wall, and against them who were coating it with whitewash, And will say to you No more is the wall, And no more are they who were coating it:", "darby": "And I will accomplish my fury upon the wall, and upon them that daub it with untempered [mortar], and will say unto you, The wall is no [more], neither they that daubed it,", "twenty": "", "jps": "Thus will I spend My fury upon the wall, and upon them that have daubed it with whited plaster; and I will say unto you: The wall is no more, neither they that daubed it;", "acv": "Thus I will accomplish my wrath upon the wall, and upon those who have daubed it with untempered mortar. And I will say to you, The wall is no more, nor those who daubed it,", "anderson": "", "haweis": "", "noyes": "Thus will I accomplish my fury upon the wall, and upon them that daubed it with untempered mortar; and I will say to you, The wall is no more, nor they that daubed it;", "webster": "Thus will I accomplish my wrath upon the wall, and upon them that have daubed it with untempered [mortar], and will say to you, The wall [is] no [more], neither they that daubed it;", "vulgate": "et conplebo indignationem meam in parietem et in his qui linunt eum absque temperamento dicamque vobis non est paries et non sunt qui linunt eum;", "brenton": "And I will accomplish my wrath upon the wall, and upon them that plaster it; it shall fall: and I said to you, The wall is not, nor they that plaster it,"}}, {"v": 16, "ref": "13:16", "o": "נְבִיאֵ֣י יִשְׂרָאֵ֗ל הַֽ/נִבְּאִים֙ אֶל יְר֣וּשָׁלִַ֔ם וְ/הַ/חֹזִ֥ים לָ֖/הּ חֲז֣וֹן שָׁלֹ֑ם וְ/אֵ֣ין שָׁלֹ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "To wit, the prophets of Israel which prophesy concerning Jerusalem, and which see visions of peace for her, and there is no peace, saith the Lord God.", "web": "to wit, the prophets of Israel who prophesy concerning Jerusalem, and who see visions of peace for her, and there is no peace, says the Lord Yahweh.", "bsb": "those prophets of Israel who prophesied to Jerusalem and saw a vision of peace for her when there was no peace, declares the Lord GOD.’", "asv": "to wit, the prophets of Israel that prophesy concerning Jerusalem, and that see visions of peace for her, and there is no peace, saith the Lord Jehovah.", "ylt": "The prophets of Israel who are prophesying concerning Jerusalem, And who are seeing for her a vision of peace, And there is no peace, An affirmation of the Lord Jehovah.", "dra": "Even the prophets of Israel that prophesy to Jerusalem, and that see visions of peace for her: and there is no peace, saith the Lord God.", "bbe": "Even the prophets of Israel who say words to Jerusalem, who see visions of peace for her when there is no peace, says the Lord.", "geneva": "To wit, the Prophets of Israel, which prophesie vpon Ierusalem, and see visions of peace for it, and there is no peace, sayth the Lord God.", "wycliffe": "that pargeten it, the profetis of Israel, that profesien to Jerusalem, and seen to it the visioun of pees, and pees is not, seith the Lord God.", "rotherham": "to wit the prophets of Israel who are prophesying unto Jerusalem, and are seeing, on her behalf, visions of prosperity,— when there is no prosperity, Declareth My Lord Yahweh.", "darby": "the prophets of Israel who prophesy concerning Jerusalem, and who see a vision of peace for her, and there is no peace, saith the Lord Jehovah.", "twenty": "", "jps": "to wit, the prophets of Israel that prophesy concerning Jerusalem, and that see visions of peace for her, and there is no peace, saith the L-rd GOD.", "acv": "namely, the prophets of Israel who prophesy concerning Jerusalem, and who see visions of peace for her, and there is no peace, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "even the prophets of Israel, who prophesy concerning Jerusalem, and see visions of peace for her when there is no peace, saith the Lord Jehovah.", "webster": "[To wit], the prophets of Israel who prophesy concerning Jerusalem, and who see visions of peace for her, and [there is] no peace, saith the Lord GOD.", "vulgate": "prophetae Israhel qui prophetant ad Hierusalem et vident ei visionem pacis et non est pax ait Dominus Deus;", "brenton": "even the prophets of Israel, who prophesy concerning Jerusalem, and who see visions of peace for her, and there is no peace, saith the Lord."}}, {"v": 17, "ref": "13:17", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם שִׂ֤ים פָּנֶ֨י/ךָ֙ אֶל בְּנ֣וֹת עַמְּ/ךָ֔ הַ/מִּֽתְנַבְּא֖וֹת מִֽ/לִּבְּ/הֶ֑ן וְ/הִנָּבֵ֖א עֲלֵי/הֶֽן", "en": {"kjv": "Likewise, thou son of man, set thy face against the daughters of thy people, which prophesy out of their own heart; and prophesy thou against them,", "web": "You, son of man, set your face against the daughters of your people, who prophesy out of their own heart; and prophesy against them,", "bsb": "Now, O son of man, set your face against the daughters of your people who prophesy out of their own imagination. Prophesy against them", "asv": "And thou, son of man, set thy face against the daughters of thy people, that prophesy out of their own heart; and prophesy thou against them,", "ylt": "And thou, son of man, set thy face against the daughters of thy people, who are prophesying out of their own heart, and prophesy concerning them,", "dra": "And thou, son of man, set thy face against the daughters of thy people that prophesy out of their own heart: and do thou prophesy against them,", "bbe": "And you, son of man, let your face be turned against the daughters of your people, who are acting the part of prophets at their pleasure; be a prophet against them, and say,", "geneva": "Likewise thou sonne of man, set thy face against the daughters of thy people, which prophesie out of their owne heart: and prophesie thou against them, and say,", "wycliffe": "And thou, sone of man, sette thi face ayens the douytris of thi puple, that profesien of her herte; and profesie thou on hem,", "rotherham": "And thou, Son of man Set thy face against the daughters of thy people, Those who are prophesying out of their own heart,— And prophesy thou against them;", "darby": "And thou, son of man, set thy face against the daughters of thy people, who prophesy out of their own heart; and prophesy against them,", "twenty": "", "jps": "And thou, son of man, set thy face against the daughters of thy people, that prophesy out of their own heart; and prophesy thou against them,", "acv": "And thou, son of man, set thy face against the daughters of thy people, who prophesy out of their own heart, and prophesy thou against them.", "anderson": "", "haweis": "", "noyes": "Likewise, son of man, set thou thy face against the daughters of thy people, who prophesy out of their own heart; and prophesy thou against them.", "webster": "Likewise, thou son of man, set thy face against the daughters of thy people, who prophesy out of their own heart; and prophesy thou against them,", "vulgate": "et tu fili hominis pone faciem tuam contra filias populi tui quae prophetant de corde suo et vaticinare super eas;", "brenton": "And thou, son of man, set thy face firmly against the daughters of thy people, that prophesy out of their own heart; and prophesy against them."}}, {"v": 18, "ref": "13:18", "o": "וְ/אָמַרְתָּ֞ כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הוֹי֩ לִֽ/מְתַפְּר֨וֹת כְּסָת֜וֹת עַ֣ל כָּל אַצִּילֵ֣י יָדַ֗/י וְ/עֹשׂ֧וֹת הַ/מִּסְפָּח֛וֹת עַל רֹ֥אשׁ כָּל קוֹמָ֖ה לְ/צוֹדֵ֣ד נְפָשׁ֑וֹת הַ/נְּפָשׁוֹת֙ תְּצוֹדֵ֣דְנָה לְ/עַמִּ֔/י וּ/נְפָשׁ֖וֹת לָ/כֶ֥נָה תְחַיֶּֽינָה", "en": {"kjv": "And say, Thus saith the Lord God; Woe to the women that sew pillows to all armholes, and make kerchiefs upon the head of every stature to hunt souls! Will ye hunt the souls of my people, and will ye save the souls alive that come unto you?", "web": "and say, Thus says the Lord Yahweh: Woe to the women who sew pillows on all elbows, and make kerchiefs for the head of persons of every stature to hunt souls! Will you hunt the souls of my people, and save souls alive for yourselves?", "bsb": "and tell them that this is what the Lord GOD says: Woe to the women who sew magic charms on their wrists and make veils for the heads of people of every height, in order to ensnare their souls. Will you ensnare the souls of My people but preserve your own?", "asv": "and say, Thus saith the Lord Jehovah: Woe to the women that sew pillows upon all elbows, and make kerchiefs for the head of persons of every stature to hunt souls! Will ye hunt the souls of my people, and save souls alive for yourselves?", "ylt": "And thou hast said: Thus said the Lord Jehovah: Woe to those sowing pillows for all joints of the arm, And to those making the kerchiefs For the head of every stature--to hunt souls, The souls do ye hunt of My people? And the souls ye have do ye keep alive?", "dra": "And say: Thus saith the Lord God: Woe to them that sew cushions under every elbow: and make pillows for the heads of persons of every age to catch souls: and when they caught the souls of my people, they gave life to their souls.", "bbe": "This is what the Lord has said: A curse is on the women who are stitching bands on all arms and putting veils on the heads of those of every size, so that they may go after souls! Will you go after the souls of my people and keep yourselves safe from death?", "geneva": "Thus sayth the Lord God, Woe vnto the women that sowe pillowes vnder al arme holes, and make vailes vpon the head of euery one that standeth vp, to hunt soules: will yee hunt ye soules of my people, and will yee giue life to the soules that come vnto you?", "wycliffe": "and seie thou, The Lord God seith these thingis, Wo to hem that sowen togidere cuschens vndur ech cubit of hond, and maken pilewis vndur the heed of ech age, to take soulis; and whanne thei disseyueden the soulis of my puple, thei quykenyden the soulis of hem.", "rotherham": "and say, Thus, saith My Lord Yahweh, Alas! for the women Who sew oracle, cases on all elbows And prepare wraps upon the head of every stature to hunt souls,— the souls ye hunt, are those of my people, Whereas your own souls:, ye keep alive.", "darby": "and say, Thus saith the Lord Jehovah: Woe unto the women that sew pillows for all wrists, and that make veils for the head [of persons] of every stature to catch souls! Will ye catch the souls of my people, and will ye save your own souls alive?", "twenty": "", "jps": "and say: Thus saith the L-rd GOD: Woe to the women that sew cushions upon all elbows, and make pads for the head of persons of every stature to hunt souls! Will ye hunt the souls of My people, and save souls alive for yourselves?", "acv": "And say, Thus says the lord Jehovah: Woe to the women who sew pillows upon all elbows, and make headdresses for the head of every stature to hunt souls! Will ye hunt the souls of my people, and save souls alive for yourselves?", "anderson": "", "haweis": "", "noyes": "And say, Thus saith the Lord Jehovah: Woe to the women that sew cushions for all elbows, and make pillows for heads of every stature, to ensnare men to destruction! Will ye hunt the lives of my people, and shall ye save your own?", "webster": "And say, Thus saith the Lord GOD; Woe to the [women] that sew pillows to all arm-holes, and make kerchiefs upon the head of every stature to hunt souls! Will ye hunt the souls of my people, and will ye save the souls alive [that come] to you?", "vulgate": "et dic haec ait Dominus Deus vae quae consuunt pulvillos sub omni cubito manus et faciunt cervicalia sub capite universae aetatis ad capiendas animas cum caperent animas populi mei vivificabant animas eorum;", "brenton": "And thou shalt say, Thus saith the Lord, Woe to the women that sew pillows under every elbow, and make kerchiefs on the head of every stature to pervert souls! The souls of my people are perverted, and they have saved souls alive."}}, {"v": 19, "ref": "13:19", "o": "וַ/תְּחַלֶּלְ֨נָה אֹתִ֜/י אֶל עַמִּ֗/י בְּ/שַׁעֲלֵ֣י שְׂעֹרִים֮ וּ/בִ/פְת֣וֹתֵי לֶחֶם֒ לְ/הָמִ֤ית נְפָשׁוֹת֙ אֲשֶׁ֣ר לֹֽא תְמוּתֶ֔נָה וּ/לְ/חַיּ֥וֹת נְפָשׁ֖וֹת אֲשֶׁ֣ר לֹא תִֽחְיֶ֑ינָה בְּ/כַ֨זֶּבְ/כֶ֔ם לְ/עַמִּ֖/י שֹׁמְעֵ֥י כָזָֽב", "en": {"kjv": "And will ye pollute me among my people for handfuls of barley and for pieces of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to my people that hear your lies?", "web": "You have profaned me among my people for handfuls of barley and for pieces of bread, to kill the souls who should not die, and to save the souls alive who should not live, by your lying to my people who listen to lies.", "bsb": "You have profaned Me among My people for handfuls of barley and scraps of bread. By lying to My people who would listen, you have killed those who should not have died and spared those who should not have lived.", "asv": "And ye have profaned me among my people for handfuls of barley and for pieces of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to my people that hearken unto lies.", "ylt": "Yea, ye pierce Me concerning My people, For handfuls of barley, And for pieces of bread, to put to death Souls that should not die, And to keep alive souls that should not live, By your lying to My people--hearkening to lies.", "dra": "And they violated me among my people, for a handful of barley, and a piece of bread, to kill souls which should not die, and to save souls alive which should not live, telling lies to my people that believe lies.", "bbe": "And you have put me to shame among my people for a little barley and some bits of bread, sending death on souls for whom there is no cause of death, and keeping those souls living who have no right to life, by the false words you say to my people who give ear to what is false.", "geneva": "And will ye pollute me among my people for handfuls of barly, and for pieces of bread to slay the soules of them that shoulde not dye, and to giue life to the soules that should not liue in lying to my people, that heare your lies?", "wycliffe": "And thei defouliden me to my puple, for an handful of barli, and for a gobet of breed, that thei schulden sle soulis that dien not, and quykene soulis that lyuen not; and thei lieden to my puple, bileuynge to leesyngis.", "rotherham": "Thus have ye profaned me unto my people for handfuls of barley and for pieces of bread, Putting to death the souls that should not die, and Keeping alive the souls that should not live,— By your lying to my people, who hearken to lies", "darby": "And will ye profane me among my people for handfuls of barley and for morsels of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to my people that listen to lying?", "twenty": "", "jps": "And ye have profaned Me among My people for handfuls of barley and for crumbs of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to My people that hearken unto lies.", "acv": "And ye have profaned me among my people for handfuls of barley and for pieces of bread, to kill the souls who should not die, and to save the souls alive who should not live, by your lying to my people who listen to lies.", "anderson": "", "haweis": "", "noyes": "And will ye pollute me among my people for handfuls of barley, and for pieces of bread, slaying them that should not die, and saving them alive that should not live, by lying to my people, who hearken to your lies?", "webster": "And will ye profane me among my people for handfuls of barley and for pieces of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to my people that hear [your] lies?", "vulgate": "et violabant me ad populum meum propter pugillum hordei et fragmen panis ut interficerent animas quae non moriuntur et vivificarent animas quae non vivunt mentientes populo meo credenti mendaciis;", "brenton": "And they have dishonoured me before my people for a handful of barley, and for pieces of bread, to slay the souls which should not die, and to save alive the souls which should not live, while ye speak to a people hearing vain speeches."}}, {"v": 20, "ref": "13:20", "o": "לָ/כֵ֞ן כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הִנְ/נִ֤י אֶל כִּסְּתוֹתֵי/כֶ֨נָה֙ אֲשֶׁ֣ר אַ֠תֵּנָה מְצֹדְד֨וֹת שָׁ֤ם אֶת הַ/נְּפָשׁוֹת֙ לְ/פֹ֣רְח֔וֹת וְ/קָרַעְתִּ֣י אֹתָ֔/ם מֵ/עַ֖ל זְרוֹעֹֽתֵי/כֶ֑ם וְ/שִׁלַּחְתִּי֙ אֶת הַ/נְּפָשׁ֔וֹת אֲשֶׁ֥ר אַתֶּ֛ם מְצֹדְד֥וֹת אֶת נְפָשִׁ֖ים לְ/פֹרְחֹֽת", "en": {"kjv": "Wherefore thus saith the Lord God; Behold, I am against your pillows, wherewith ye there hunt the souls to make them fly, and I will tear them from your arms, and will let the souls go, even the souls that ye hunt to make them fly.", "web": "Therefore thus says the Lord Yahweh: Behold, I am against your pillows, with which you there hunt the souls to make them fly, and I will tear them from your arms; and I will let the souls go, even the souls whom you hunt to make them fly.", "bsb": "Therefore this is what the Lord GOD says: See, I am against the magic charms with which you ensnare souls like birds, and I will tear them from your arms. So I will free the souls you have ensnared like birds.", "asv": "Wherefore thus saith the Lord Jehovah: Behold, I am against your pillows, wherewith ye there hunt the souls to make them fly, and I will tear them from your arms; and I will let the souls go, even the souls that ye hunt to make them fly.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am against your pillows, With which ye are hunting there the souls of the flourishing, And I have rent them from off your arms, And have sent away the souls that ye are hunting, The souls of the flourishing.", "dra": "Therefore thus saith the Lord God: Behold I declare against your cushions, wherewith you catch flying souls: and I will tear them off from your arms: and I will let go the soul that you catch, the souls that should fly.", "bbe": "For this cause the Lord has said: See, I am against your bands with which you go after souls, and I will violently take them off their arms; and I will let loose the souls, even the souls whom you go after freely.", "geneva": "Wherefore thus saith the Lord God, Behold, I will haue to do with your pillowes, wherewith yee hunt the soules to make them to flie, and I will teare them from your armes, and will let the soules goe, euen the soules, that ye hunt to make them to flie.", "wycliffe": "For this thing the Lord God seith these thingis, Lo! Y to youre cuschens, bi whiche ye disseyuen soulis fliynge; and Y schal al to-breke tho fro youre armes, and Y schal delyuere soulis which ye disseyuen, soulis to fle.", "rotherham": "Therefore, Thus saith my Lord Yahweh, Behold me! against your oracle-cases wherewith ye are hunting the souls to make them fly, And I will tear them off your arms, And let go the souls of them whose souls ye are hunting as birds;", "darby": "Wherefore thus saith the Lord Jehovah: Behold, I am against your pillows, that the souls which ye catch by their means may fly away; and I will tear them from your arms, and will let the souls go, the souls that ye catch, that they may fly away.", "twenty": "", "jps": "Wherefore thus saith the L-rd GOD: Behold, I am against your cushions, wherewith ye hunt the souls as birds, and I will tear them from your arms; and I will let the souls go, even the souls that ye hunt as birds.", "acv": "Therefore thus says the lord Jehovah: Behold, I am against your pillows, with which ye hunt the souls there to make fly, and I will tear them from your arms. And I will let the souls go, even the souls that ye hunt to make fly.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, I will set myself against the cushions with which ye ensnare men to destruction, so that they shall escape you; and I will tear them from your arms, and make them free whom ye would ensnare, so that they shall escape you.", "webster": "Wherefore thus saith the Lord GOD; Behold, I [am] against your pillows, with which ye there hunt the souls to make [them] fly, and I will tear them from your arms, and will let the souls go, [even] the souls that ye hunt to make [them] fly.", "vulgate": "propter hoc haec dicit Dominus Deus ecce ego ad pulvillos vestros quibus vos capitis animas volantes et disrumpam eos de brachiis vestris et dimittam animas quas vos capitis animas ad volandum;", "brenton": "Therefore thus saith the Lord God, Behold, I am against your pillows, whereby ye there confound souls, and I will tear them away from your arms, and will set at liberty their souls which ye pervert to scatter them."}}, {"v": 21, "ref": "13:21", "o": "וְ/קָרַעְתִּ֞י אֶת מִסְפְּחֹֽתֵי/כֶ֗ם וְ/הִצַּלְתִּ֤י אֶת עַמִּ/י֙ מִ/יֶּדְ/כֶ֔ן וְ/לֹֽא יִהְי֥וּ ע֛וֹד בְּ/יֶדְ/כֶ֖ן לִ/מְצוּדָ֑ה וִֽ/ידַעְתֶּ֖ן כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Your kerchiefs also will I tear, and deliver my people out of your hand, and they shall be no more in your hand to be hunted; and ye shall know that I am the Lord.", "web": "Your kerchiefs also will I tear, and deliver my people out of your hand, and they shall be no more in your hand to be hunted; and you shall know that I am Yahweh.", "bsb": "I will also tear off your veils and deliver My people from your hands, so that they will no longer be prey in your hands. Then you will know that I am the LORD.", "asv": "Your kerchiefs also will I tear, and deliver my people out of your hand, and they shall be no more in your hand to be hunted; and ye shall know that I am Jehovah.", "ylt": "And I have torn your kerchiefs, And delivered My people out of your hand, And they are no more in your hand for a prey, And ye have known that I am Jehovah.", "dra": "And I will tear your pillows, and will deliver my people out of your hand, neither shall they be any more in your hands to be a prey: and you shall know that I am the Lord.", "bbe": "And I will have your veils violently parted in two, and will make my people free from your hands, and they will no longer be in your power for you to go after them; and you will be certain that I am the Lord.", "geneva": "Your vailes also will I teare, and deliuer my people out of your hande, and they shalbe no more in your hands to be hunted, and ye shall knowe that I am the Lord.", "wycliffe": "And Y schal al to-breke youre pilewis, and Y schal delyuere my puple fro youre hond; and thei schulen no more be in youre hondis, to be robbid; and ye schulen wite, that Y am the Lord.", "rotherham": "And will tear off your wraps, And deliver my people out of your hand, And they shall be no longer in your hand to be hunted;- So shall ye know that, I, am Yahweh.", "darby": "And I will tear your veils and deliver my people out of your hand, and they shall be no more in your hand to be hunted; and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "Your pads also will I tear, and deliver My people out of your hand, and they shall be no more in your hand to be hunted; and ye shall know that I am HaShem.", "acv": "I will also tear your headdresses, and deliver my people out of your hand, and they shall no more be in your hand to be hunted. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "Your pillows also will I tear, and deliver my people out of your hand, and they shall no more be in your hand to be ensnared, and ye shall know that I am Jehovah.", "webster": "Your kerchiefs also will I tear, and deliver my people out of your hand, and they shall no more be in your hand to be hunted; and ye shall know that I [am] the LORD.", "vulgate": "et disrumpam cervicalia vestra et liberabo populum meum de manu vestra neque erunt ultra in manibus vestris ad praedandum et scietis quia ego Dominus;", "brenton": "And I will tear your kerchiefs, and will rescue my people out of your hands, and they shall no longer be in your hands to be confounded; and ye shall know that I am the Lord."}}, {"v": 22, "ref": "13:22", "o": "יַ֣עַן הַכְא֤וֹת לֵב צַדִּיק֙ שֶׁ֔קֶר וַ/אֲנִ֖י לֹ֣א הִכְאַבְתִּ֑י/ו וּ/לְ/חַזֵּק֙ יְדֵ֣י רָשָׁ֔ע לְ/בִלְתִּי שׁ֛וּב מִ/דַּרְכּ֥/וֹ הָ/רָ֖ע לְ/הַחֲיֹתֽ/וֹ", "en": {"kjv": "Because with lies ye have made the heart of the righteous sad, whom I have not made sad; and strengthened the hands of the wicked, that he should not return from his wicked way, by promising him life:", "web": "Because with lies you have grieved the heart of the righteous, whom I have not made sad; and strengthened the hands of the wicked, that he should not return from his wicked way, and be saved alive:", "bsb": "Because you have disheartened the righteous with your lies, even though I have caused them no grief, and because you have encouraged the wicked not to turn from their evil ways to save their lives,", "asv": "Because with lies ye have grieved the heart of the righteous, whom I have not made sad, and strengthened the hands of the wicked, that he should not return from his wicked way, and be saved alive;", "ylt": "Because of paining the heart of the righteous with falsehood, And I have not pained it, And strengthening the hands of the wicked, So as not to turn back from his evil way, To keep him alive,", "dra": "Because with lies you have made the heart of the just to mourn, whom I have not made sorrowful: and have strengthened the hands of the wicked, that he should not return from his evil way, and live.", "bbe": "Because with your false words you have given pain to the heart of the upright man when I had not made him sad; in order to make strong the hands of the evil-doer so that he may not be turned from his evil way and get life:", "geneva": "Because with your lyes yee haue made the heart of the righteous sadde, whome I haue not made sad, and strengthened the hands of the wicked, that he should not returne from his wicked way, by promising him life,", "wycliffe": "For that that ye maden falsli the herte of a iust man to morene, whom Y made not sori; and ye coumfortiden the hondis of a wickid man, that he schulde not turne ayen fro his yuel weie, and lyue.", "rotherham": "Because of the paining of the heart of the righteous man with falsehood, whom, I, have not pained,— And strengthening the hands of the lawless man, that he should not turn from his wicked way. by letting him live", "darby": "Because with falsehood ye have grieved the heart of the righteous, whom I have not made sad; and have strengthened the hands of the wicked, that he should not return from his wicked way, to save his life:", "twenty": "", "jps": "Because with lies ye have cowed the heart of the righteous, when I have not grieved him; and strengthened the hands of the wicked, that he should not return from his wicked way, that he be saved alive;", "acv": "Because with lies ye have grieved the heart of the righteous, whom I have not made sad, and strengthened the hands of the wicked, that he should not return from his wicked way, and be saved alive.", "anderson": "", "haweis": "", "noyes": "Because with lies ye have made sad the heart of the righteous, whom I have not made sad, and have strengthened the hands of the wicked, that he should not return from his wicked way, by promising him life;", "webster": "Because with lies ye have made the heart of the righteous sad, whom I have not made sad; and strengthened the hands of the wicked, that he should not return from his wicked way, by promising him life:", "vulgate": "pro eo quod maerere fecistis cor iusti mendaciter quem ego non contristavi et confortastis manus impii ut non reverteretur a via sua mala et viveret;", "brenton": "Because ye have perverted the heart of the righteous, whereas I perverted him not, and that in order to strengthen the hands of the wicked, that he should not at all turn from his evil way and live:"}}, {"v": 23, "ref": "13:23", "o": "לָ/כֵ֗ן שָׁ֚וְא לֹ֣א תֶחֱזֶ֔ינָה וְ/קֶ֖סֶם לֹא תִקְסַ֣מְנָה ע֑וֹד וְ/הִצַּלְתִּ֤י אֶת עַמִּ/י֙ מִ/יֶּדְ/כֶ֔ן וִֽ/ידַעְתֶּ֖ן כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Therefore ye shall see no more vanity, nor divine divinations: for I will deliver my people out of your hand: and ye shall know that I am the Lord.", "web": "Therefore you shall no more see false visions, nor practice divination. I will deliver my people out of your hand; and you shall know that I am Yahweh.", "bsb": "therefore you will no longer see false visions or practice divination. I will deliver My people from your hands. Then you will know that I am the LORD.”", "asv": "Therefore ye shall no more see false visions, nor divine divinations: and I will deliver my people out of your hand; and ye shall know that I am Jehovah.", "ylt": "Therefore, vanity ye do not see, And divination ye do not divine again, And I have delivered My people out of your hand, And ye have known that I am Jehovah!'", "dra": "Therefore you shall not see vain things, nor divine divinations any more, and I will deliver my people out of your hand: and you shall know that I am the Lord.", "bbe": "For this cause you will see no more foolish visions or make false use of secret arts: and I will make my people free from your power; and you will be certain that I am the Lord.", "geneva": "Therefore ye shall see no more vanitie, nor diuine diuinatios: for I wil deliuer my people out of your hand, and ye shall know that I am ye Lord.", "wycliffe": "Therfor ye schulen not se veyn thingis, and ye schulen no more dyuyne false dyuynyngis; and Y schal delyuere my puple fro youre hond, and ye schulen wite, that Y am the Lord.", "rotherham": "Therefore—of falsehood:, shall ye have no vision, And a divination:, shall ye not divine any more,— So will I deliver my people out of your hand, And ye shall know that, I, am Yahweh.", "darby": "therefore ye shall no more see vanity, nor divine divinations; and I will deliver my people out of your hand: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "therefore ye shall no more see vanity, nor divine divinations; and I will deliver My people out of your hand; and ye shall know that I am HaShem.'", "acv": "Therefore ye shall no more see false visions, nor divine divinations. And I will deliver my people out of your hand. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "therefore shall ye no more see falsehood, nor divine divinations; but I will deliver my people out of your hand, and ye shall know that I am Jehovah.", "webster": "Therefore ye shall see no more vanity, nor divine divinations: for I will deliver my people out of your hand: and ye shall know that I [am] the LORD.", "vulgate": "propterea vana non videbitis et divinationes non divinabitis amplius et eruam populum meum de manu vestra et scietis quoniam ego Dominus;", "brenton": "therefore ye shall not see false visions, and ye shall no more utter prophecies: but I will deliver my people out of your hand; and ye shall know that I am the Lord."}}]}, {"c": 14, "verses": [{"v": 1, "ref": "14:1", "o": "וַ/יָּב֤וֹא אֵלַ/י֙ אֲנָשִׁ֔ים מִ/זִּקְנֵ֖י יִשְׂרָאֵ֑ל וַ/יֵּשְׁב֖וּ לְ/פָנָֽ/י", "en": {"kjv": "Then came certain of the elders of Israel unto me, and sat before me.", "web": "Then came certain of the elders of Israel to me, and sat before me.", "bsb": "Then some of the elders of Israel came and sat down before me.", "asv": "Then came certain of the elders of Israel unto me, and sat before me.", "ylt": "And come in unto me do certain of the elders of Israel, and sit before me.", "dra": "And some of the ancients of Israel came to me, and sat before me.", "bbe": "Then certain of the responsible men of Israel came to me and took their seats before me.", "geneva": "Then came certaine of the Elders of Israel vnto me, and sate before me.", "wycliffe": "And men of the eldris of Israel camen to me, and saten bifor me.", "rotherham": "Then came there unto me men, of the elders of Israel,—and sat before me—", "darby": "And there came certain of the elders of Israel unto me, and sat before me.", "twenty": "", "jps": "Then came certain of the elders of Israel unto me, and sat before me.", "acv": "Then certain of the elders of Israel came to me, and sat before me.", "anderson": "", "haweis": "", "noyes": "Now certain men of the elders of Israel came to me, and sat before me.", "webster": "Then came certain of the elders of Israel to me, and sat before me.", "vulgate": "et venerunt ad me viri seniorum Israhel et sederunt coram me;", "brenton": "And there came to me men of the people of Israel, of the elders, and sat before me."}}, {"v": 2, "ref": "14:2", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide, Sone of man,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 3, "ref": "14:3", "o": "בֶּן אָדָ֗ם הָ/אֲנָשִׁ֤ים הָ/אֵ֨לֶּה֙ הֶעֱל֤וּ גִלּֽוּלֵי/הֶם֙ עַל לִבָּ֔/ם וּ/מִכְשׁ֣וֹל עֲוֺנָ֔/ם נָתְנ֖וּ נֹ֣כַח פְּנֵי/הֶ֑ם הַ/אִדָּרֹ֥שׁ אִדָּרֵ֖שׁ לָ/הֶֽם", "en": {"kjv": "Son of man, these men have set up their idols in their heart, and put the stumblingblock of their iniquity before their face: should I be enquired of at all by them?", "web": "Son of man, these men have taken their idols into their heart, and put the stumbling block of their iniquity before their face: should I be inquired of at all by them?", "bsb": "“Son of man, these men have set up idols in their hearts and put wicked stumbling blocks before their faces. Should I consult with them in any way?", "asv": "Son of man, these men have taken their idols into their heart, and put the stumblingblock of their iniquity before their face: should I be inquired of at all by them?", "ylt": "`Son of man, these men have caused their idols to go up on their heart, and the stumbling-block of their iniquity they have put over-against their faces; am I inquired of at all by them?", "dra": "Son of man, these men have placed their uncleannesses in their hearts, and have set up before their face the stumblingblock of their iniquity: and shall I answer when they inquire of me?", "bbe": "Son of man, these men have taken their false gods into their hearts and put before their faces the sin which is the cause of their fall: am I to give ear when they come to me for directions?", "geneva": "Sonne of man, these men haue set vp their idoles in their heart, and put the stumbling blocke of their iniquitie before their face: should I, being required, answere them?", "wycliffe": "these men han set her vnclennesses in her hertis, and han set stidfastli the sclaundre of her wickidnesse ayens her face. Whether Y `that am axid, schal answere to hem?", "rotherham": "Son of man These men have brought up their manufactured gods upon their hear, And their stumbling-block of iniquity, have they set straight before their face, —Shall I be at all enquired of by them?", "darby": "Son of man, these men have set up their idols in their heart, and put the stumbling-block of their iniquity before their face: should I be inquired of at all by them?", "twenty": "", "jps": "'Son of man, these men have set up their idols in their mind, and put the stumblingblock of their iniquity before their face; should I be inquired of at all by them?", "acv": "Son of man, these men have taken their idols into their heart, and put the stumbling block of their iniquity before their face. Should I be inquired of at all by them?", "anderson": "", "haweis": "", "noyes": "Son of man, these men have set up their idols in their heart, and have put the stumbling-block of their iniquity before their face; shall I hear them when they inquire of me?", "webster": "Son of man, these men have set up their idols in their heart, and put the stumbling-block of their iniquity before their face: should I be inquired of at all by them?", "vulgate": "fili hominis viri isti posuerunt inmunditias suas in cordibus suis et scandalum iniquitatis suae statuerunt contra faciem suam numquid interrogatus respondebo eis;", "brenton": "Son of man, these men have conceived their devices in their hearts, and have set before their faces the punishment of their iniquities: shall I indeed answer them?"}}, {"v": 4, "ref": "14:4", "o": "לָ/כֵ֣ן דַּבֵּר א֠וֹתָ/ם וְ/אָמַרְתָּ֨ אֲלֵי/הֶ֜ם כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה אִ֣ישׁ אִ֣ישׁ מִ/בֵּ֣ית יִשְׂרָאֵ֡ל אֲשֶׁר֩ יַעֲלֶ֨ה אֶת גִּלּוּלָ֜י/ו אֶל לִבּ֗/וֹ וּ/מִכְשׁ֤וֹל עֲוֺנ/וֹ֙ יָשִׂים֙ נֹ֣כַח פָּנָ֔י/ו וּ/בָ֖א אֶל הַ/נָּבִ֑יא אֲנִ֣י יְהוָ֗ה נַעֲנֵ֧יתִי ל֦/וֹ ב/ה בָ֖א בְּ/רֹ֥ב גִּלּוּלָֽי/ו", "en": {"kjv": "Therefore speak unto them, and say unto them, Thus saith the Lord God; Every man of the house of Israel that setteth up his idols in his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet; I the Lord will answer him that cometh according to the multitude of his idols;", "web": "Therefore speak to them, and tell them, Thus says the Lord Yahweh: Every man of the house of Israel who takes his idols into his heart, and puts the stumbling block of his iniquity before his face, and comes to the prophet; I Yahweh will answer him therein according to the multitude of his idols;", "bsb": "Therefore speak to them and tell them that this is what the Lord GOD says: ‘When any Israelite sets up idols in his heart and puts a wicked stumbling block before his face, and then comes to the prophet, I the LORD will answer him according to his great idolatry,", "asv": "Therefore speak unto them, and say unto them, Thus saith the Lord Jehovah: Every man of the house of Israel that taketh his idols into his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet; I Jehovah will answer him therein according to the multitude of his idols;", "ylt": "`Therefore, speak with them, and thou hast said unto them: Thus said the Lord Jehovah: Every one of the house of Israel who causeth his idols to go up unto his heart, and the stumbling-block of his iniquity setteth over-against his face, and hath gone in unto the prophet--I Jehovah have given an answer to him for this, for the abundance of his idols,", "dra": "Therefore speak to them, and say to them: Thus saith the Lord God: Man, man of the house of Israel that shall place his uncleannesses in his heart, and set up the stumblingblock of his iniquity before his face, and shall come to the prophet inquiring of me by him: I the Lord will answer him according to the multitude of his uncleannesses:", "bbe": "For this cause say to them, These are the words of the Lord: Every man of Israel who has taken his false god into his heart, and put before his face the sin which is the cause of his fall, and comes to the prophet; I the Lord will give him an answer by myself in agreement with the number of his false gods;", "geneva": "Therefore speake vnto them, and say vnto them, Thus saith the Lord God, Euery man of the house of Israel that setteth vp his idols in his heart, and putteth the stumbling blocke of his iniquitie before his face, and commeth to the Prophet, I the Lord will answere him that commeth, according to the multitude of his idoles:", "wycliffe": "For this thing speke thou to hem, and thou schalt seie to hem, These thingis seith the Lord God, A man, a man of the hous of Israel, that settith hise vnclennessis in his herte, and settith stidfastli the sclaundre of his wickidnesse ayens his face, and cometh to the profete, and axith me bi hym, Y the Lord schal answere to hym in the multitude of hise vnclennessis;", "rotherham": "Therefore speak unto them and say unto them, Thus, saith My Lord, Yahweh, Any man whatsoever of the house of Israel Who shall bring up his manufactured gods upon his heart, And set, his stumbling-block of iniquity, straight before his face, And then come in unto the prophet, I Yahweh, have myself answered him thereby. By the multitude of his manufactured gods:", "darby": "Therefore speak to them, and say unto them, Thus saith the Lord Jehovah: Every man of the house of Israel that setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to the prophet, I Jehovah will answer him according to this, according to the multitude of his idols:", "twenty": "", "jps": "Therefore speak unto them, and say unto them: Thus saith the L-rd GOD: Every man of the house of Israel that setteth up his idols in his mind, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet--I HaShem will answer him that cometh according to the multitude of his idols;", "acv": "Therefore speak to them, and say to them, Thus says the lord Jehovah: Every man of the house of Israel who takes his idols into his heart, and puts the stumbling block of his iniquity before his face, and comes to the prophet, I Jehovah will answer him in it according to the multitude of his idols,", "anderson": "", "haweis": "", "noyes": "Therefore speak with them, and say to them, Thus saith the Lord Jehovah: Every man of the house of Israel that setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to the prophet,—I, Jehovah, will answer him according to the multitude of his idols;", "webster": "Therefore speak to them, and say to them, Thus saith the Lord GOD; Every man of the house of Israel that setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to the prophet; I the LORD will answer him that cometh according to the multitude of his idols;", "vulgate": "propter hoc loquere eis et dices ad eos haec dicit Dominus Deus homo homo de domo Israhel qui posuerit inmunditias suas in corde suo et scandalum iniquitatis suae statuerit contra faciem suam et venerit ad prophetam interrogans per eum me ego Dominus respondebo ei in multitudine inmunditiarum suarum;", "brenton": "Therefore speak to them, and thou shalt say to them, Thus saith the Lord; Any man of the house of Israel, who shall conceive his devices in his heart, and shall set the punishment of his iniquity before his face, and shall come to the prophet; I the Lord will answer him according to the things in which his mind is entangled,"}}, {"v": 5, "ref": "14:5", "o": "לְמַ֛עַן תְּפֹ֥שׂ אֶת בֵּֽית יִשְׂרָאֵ֖ל בְּ/לִבָּ֑/ם אֲשֶׁ֤ר נָזֹ֨רוּ֙ מֵֽ/עָלַ֔/י בְּ/גִלּֽוּלֵי/הֶ֖ם כֻּלָּֽ/ם", "en": {"kjv": "That I may take the house of Israel in their own heart, because they are all estranged from me through their idols.", "web": "that I may take the house of Israel in their own heart, because they are all estranged from me through their idols.", "bsb": "so that I may take hold of the hearts of the people of Israel. For because of their idols, they are all estranged from Me.’", "asv": "that I may take the house of Israel in their own heart, because they are all estranged from me through their idols.", "ylt": "in order to catch the house of Israel by their heart, in that they have become estranged from off me by their idols--all of them.", "dra": "That the house of Israel may be caught in their own heart, with which they have departed from me through all their idols.", "bbe": "So as to take the children of Israel in the thoughts of their hearts, because they have become strange to me through their false gods.", "geneva": "That I may take the house of Israel in their owne heart, because they are all departed from me through their idoles.", "wycliffe": "that the hous of Israel be takun in her herte, bi which thei yeden awei fro me in alle her idols.", "rotherham": "To the end the house of Israel may be taken by their own hearts,—in that they have estranged themselves from me, through their manufactured gods—all of them!", "darby": "that I may take the house of Israel by their own heart, because they are all estranged from me through their idols.", "twenty": "", "jps": "that I may take the house of Israel in their own heart, because they are all turned away from Me through their idols.", "acv": "that I may take the house of Israel in their own heart, because they are all estranged from me through their idols.", "anderson": "", "haweis": "", "noyes": "that I may lay hold of the house of Israel in their hearts, because they are all estranged from me through their idols.", "webster": "That I may take the house of Israel in their own heart, because they are all estranged from me through their idols.", "vulgate": "ut capiatur domus Israhel in corde suo quo recesserunt a me in cunctis idolis suis;", "brenton": "that he should turn aside the house of Israel, according to their hearts that are estranged from me in their thoughts."}}, {"v": 6, "ref": "14:6", "o": "לָ/כֵ֞ן אֱמֹ֣ר אֶל בֵּ֣ית יִשְׂרָאֵ֗ל כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה שׁ֣וּבוּ וְ/הָשִׁ֔יבוּ מֵ/עַ֖ל גִּלּֽוּלֵי/כֶ֑ם וּ/מֵ/עַ֥ל כָּל תּוֹעֲבֹתֵי/כֶ֖ם הָשִׁ֥יבוּ פְנֵי/כֶֽם", "en": {"kjv": "Therefore say unto the house of Israel, Thus saith the Lord God; Repent, and turn yourselves from your idols; and turn away your faces from all your abominations.", "web": "Therefore tell the house of Israel, Thus says the Lord Yahweh: Return, and turn yourselves from your idols; and turn away your faces from all your abominations.", "bsb": "Therefore tell the house of Israel that this is what the Lord GOD says: ‘Repent and turn away from your idols; turn your faces away from all your abominations.", "asv": "Therefore say unto the house of Israel, Thus saith the Lord Jehovah: Return ye, and turn yourselves from your idols; and turn away your faces from all your abominations.", "ylt": "`Therefore say unto the house of Israel: Thus said the Lord Jehovah: Turn ye back, yea, turn ye back from your idols, and from all your abominations turn back your faces,", "dra": "Therefore say to the house of Israel: Thus saith the Lord God: Be converted, and depart from your idols, and turn away your faces from all your abominations.", "bbe": "For this cause say to the children of Israel, These are the words of the Lord: Come back and give up your false gods and let your faces be turned from your disgusting things.", "geneva": "Therfore say vnto the house of Israel, Thus sayth the Lord God, Returne, and withdraw your selues, and turne your faces from your idoles, and turne your faces from all your abominations.", "wycliffe": "Therfor seie thou to the hous of Israel, The Lord God seith these thingis, Be ye conuertid, and go ye awei fro youre idols, and turne awei youre faces fro alle youre filthis.", "rotherham": "Therefore, say thou unto the house of Israel, Thus, saith My Lord Yahweh, Turn ye—and make good your return—from your manufactured gods; And, from all your abominations, make good the turning away of your faces.", "darby": "Therefore say unto the house of Israel, Thus saith the Lord Jehovah: Return ye, and turn yourselves from your idols; and turn away your faces from all your abominations.", "twenty": "", "jps": "Therefore say unto the house of Israel: Thus saith the L-rd GOD: Return ye, and turn yourselves from your idols; and turn away your faces from all your abominations.", "acv": "Therefore say to the house of Israel, Thus says the lord Jehovah: Return ye, and turn yourselves from your idols, and turn away your faces from all your abominations.", "anderson": "", "haweis": "", "noyes": "Therefore say to the house of Israel, Thus saith the Lord Jehovah: Turn ye, even turn yourselves from your idols, and from all your abominations turn ye your faces!", "webster": "Therefore say to the house of Israel, Thus saith the Lord GOD; Repent, and turn [yourselves] from your idols; and turn away your faces from all your abominations.", "vulgate": "propterea dic ad domum Israhel haec dicit Dominus Deus convertimini et recedite ab idolis vestris et ab universis contaminationibus vestris avertite facies vestras;", "brenton": "Therefore say to the house of Israel, Thus saith the Lord God, Be converted, and turn from your evil practices, and from all your sins, and turn your faces back again."}}, {"v": 7, "ref": "14:7", "o": "כִּי֩ אִ֨ישׁ אִ֜ישׁ מִ/בֵּ֣ית יִשְׂרָאֵ֗ל וּ/מֵ/הַ/גֵּר֮ אֲשֶׁר יָג֣וּר בְּ/יִשְׂרָאֵל֒ וְ/יִנָּזֵ֣ר מֵֽ/אַחֲרַ֗/י וְ/יַ֤עַל גִּלּוּלָי/ו֙ אֶל לִבּ֔/וֹ וּ/מִכְשׁ֣וֹל עֲוֺנ֔/וֹ יָשִׂ֖ים נֹ֣כַח פָּנָ֑י/ו וּ/בָ֤א אֶל הַ/נָּבִיא֙ לִ/דְרָשׁ ל֣/וֹ בִ֔/י אֲנִ֣י יְהוָ֔ה נַֽעֲנֶה לּ֖/וֹ בִּֽ/י", "en": {"kjv": "For every one of the house of Israel, or of the stranger that sojourneth in Israel, which separateth himself from me, and setteth up his idols in his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to a prophet to enquire of him concerning me; I the Lord will answer him by myself:", "web": "For everyone of the house of Israel, or of the strangers who live in Israel, who separates himself from me, and takes his idols into his heart, and puts the stumbling block of his iniquity before his face, and comes to the prophet to inquire for himself of me; I Yahweh will answer him by myself:", "bsb": "For when any Israelite or any foreigner dwelling in Israel separates himself from Me, sets up idols in his heart, and puts a wicked stumbling block before his face, and then comes to the prophet to inquire of Me, I the LORD will answer him Myself.", "asv": "For every one of the house of Israel, or of the strangers that sojourn in Israel, that separateth himself from me, and taketh his idols into his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet to inquire for himself of me; I Jehovah will answer him by myself:", "ylt": "for every one of the house of Israel, and of the sojourners who doth sojourn in Israel, who is separated from after Me, and doth cause his idols to go up unto his heart, and the stumbling-block of his iniquity setteth over-against his face, and hath come in unto the prophet to inquire of him concerning Me, I, Jehovah, have answered him for Myself;", "dra": "For every man of the house of Israel, and every stranger among the proselytes in Israel, if he separate himself from me, and place his idols in his heart, and set the stumblingblock of his iniquity before his face, and come to the prophet to inquire of me by him: I the Lord will answer him by myself.", "bbe": "When any one of the men of Israel, or of those from other lands who are living in Israel, who has become strange to me, and takes his false gods into his heart, and puts before his face the sin which is the cause of his fall, comes to the prophet to get directions from me; I the Lord will give him an answer by myself:", "geneva": "For euery one of the house of Israel, or of the stranger that soiourneth in Israel, which departeth from mee, and setteth vp his idoles in his heart, and putteth the stumbling blocke of his iniquitie before his face, and commeth to a Prophet, for to inquire of him for me, I the Lord will answere him for my selfe,", "wycliffe": "For whi a man, a man of the hous of Israel, and of conuersis, who euer is a comelyng in Israel, if he is alienyd fro me, and settith hise idols in his herte, and settith stidfastli the sclaundir of his wickidnesse ayens his face, and he cometh to the profete, to axe me bi hym, Y the Lord schal answere hym bi my silf.", "rotherham": "For what man soever of the house of Israel Or of the sojourners who sojourn in Israel, Who shall estrange himself from following me And who shall bring up his manufactured gods, on his heart, And whose stumbling-block of iniquity, he shall set straight before his face, And then come in unto the prophet, to enquire by him of me, I Yahweh, will myself answer him, on my own account;", "darby": "For every one of the house of Israel, or of the strangers that sojourn in Israel, who separateth himself from me, and setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to the prophet to inquire of me by him, I Jehovah will answer him by myself;", "twenty": "", "jps": "For every one of the house of Israel, or of the strangers that sojourn in Israel, that separateth himself from Me, and taketh his idols into his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet, that he inquire for him of Me--I HaShem will answer him by Myself,", "acv": "For everyone of the house of Israel, or of the strangers who sojourn in Israel, that separates himself from me, and takes his idols into his heart, and puts the stumbling block of his iniquity before his face, and comes to the prophet to inquire for himself of me, I Jehovah will answer him by myself.", "anderson": "", "haweis": "", "noyes": "For every one of the house of Israel, or of the strangers that sojourn in Israel, who separateth himself from me, and setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to the prophet to inquire of me through him,—I, Jehovah, will answer him by myself.", "webster": "For every one of the house of Israel, or of the stranger that sojourneth in Israel, who separateth himself from me, and setteth up his idols in his heart, and putteth the stumbling-block of his iniquity before his face, and cometh to a prophet to inquire of him concerning me; I the LORD will answer him by myself:", "vulgate": "quia homo homo de domo Israhel et de proselytis quicumque advena fuerit in Israhel si alienatus fuerit a me et posuerit idola sua in corde suo et scandalum iniquitatis suae statuerit contra faciem suam et venerit ad prophetam ut interroget per eum me ego Dominus respondebo ei per me;", "brenton": "For any man of the house of Israel, or of the strangers that sojourn in Israel, who shall separate himself from me, and conceive his imaginations in his heart, and set before his face the punishment of his iniquity, and come to the prophet to enquire of him concerning me; I the Lord will answer him, according to the things wherein he is entangled."}}, {"v": 8, "ref": "14:8", "o": "וְ/נָתַתִּ֨י פָנַ֜/י בָּ/אִ֣ישׁ הַ/ה֗וּא וַ/הֲשִֽׂמֹתִ֨י/הוּ֙ לְ/א֣וֹת וְ/לִ/מְשָׁלִ֔ים וְ/הִכְרַתִּ֖י/ו מִ/תּ֣וֹךְ עַמִּ֑/י וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will set my face against that man, and will make him a sign and a proverb, and I will cut him off from the midst of my people; and ye shall know that I am the Lord.", "web": "and I will set my face against that man, and will make him an astonishment, for a sign and a proverb, and I will cut him off from the midst of my people; and you shall know that I am Yahweh.", "bsb": "I will set My face against that man and make him a sign and a proverb; I will cut him off from among My people. Then you will know that I am the LORD.", "asv": "and I will set my face against that man, and will make him an astonishment, for a sign and a proverb, and I will cut him off from the midst of my people; and ye shall know that I am Jehovah.", "ylt": "and I have set My face against that man, and made him for a sign, and for similes, and I have cut him off from the midst of My people, and ye have known that I am Jehovah.", "dra": "And I will set my face against that man, and will make him an example, and a proverb, and will cut him off from the midst of my people: and you shall know that I am the Lord.", "bbe": "And my face will be turned against that man, and I will make him a sign and a common saying, cutting him off from among my people; and you will be certain that I am the Lord.", "geneva": "And I will set my face against that man, and will make him an example and prouerbe, and I will cut him off from the middes of my people, and ye shall knowe that I am the Lord.", "wycliffe": "And Y schal sette my face on that man, and Y schal make hym in to ensaumple, and in to a prouerbe, and Y schal leese hym fro the myddis of my puple; and ye schulen wite, that Y am the Lord.", "rotherham": "And will set my face against that man And will make of him a sign and a proverb, And will cut him off out of the midst of my people: So shall ye know that, I, am Yahweh.", "darby": "and I will set my face against that man, and will make him desolate, [so that he shall be] for a sign and for proverbs, and I will cut him off from the midst of my people: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "and I will set My face against that man, and will make him a sign and a proverb, and I will cut him off from the midst of My people; and ye shall know that I am HaShem.", "acv": "And I will set my face against that man, and will make him an astonishment, for a sign and a proverb. And I will cut him off from the midst of my people. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will set my face against that man, and will make him a sign and a proverb, and will cut him off from the midst of my people; and ye shall know that I am Jehovah.", "webster": "And I will set my face against that man, and will make him a sign and a proverb, and I will cut him off from the midst of my people; and ye shall know that I [am] the LORD.", "vulgate": "et ponam faciem meam super hominem illum et faciam eum in exemplum et in proverbium et disperdam eum de medio populi mei et scietis quia ego Dominus;", "brenton": "And I will set my face against that man, and will make him desolate and ruined, and will cut him off from the midst of my people; and ye shall know that I am the Lord."}}, {"v": 9, "ref": "14:9", "o": "וְ/הַ/נָּבִ֤יא כִֽי יְפֻתֶּה֙ וְ/דִבֶּ֣ר דָּבָ֔ר אֲנִ֤י יְהוָה֙ פִּתֵּ֔יתִי אֵ֖ת הַ/נָּבִ֣יא הַ/ה֑וּא וְ/נָטִ֤יתִי אֶת יָדִ/י֙ עָלָ֔י/ו וְ/הִ֨שְׁמַדְתִּ֔י/ו מִ/תּ֖וֹךְ עַמִּ֥/י יִשְׂרָאֵֽל", "en": {"kjv": "And if the prophet be deceived when he hath spoken a thing, I the Lord have deceived that prophet, and I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.", "web": "If the prophet is deceived and speak a word, I, Yahweh, have deceived that prophet, and I will stretch out my hand on him, and will destroy him from the midst of my people Israel.", "bsb": "But if the prophet is enticed to speak a message, then it was I the LORD who enticed him, and I will stretch out My hand against him and destroy him from among My people Israel.", "asv": "And if the prophet be deceived and speak a word, I, Jehovah, have deceived that prophet, and I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.", "ylt": "`And the prophet, when he is enticed, and hath spoken a word--I, Jehovah, I have enticed that prophet, and have stretched out My hand against him, and have destroyed him from the midst of My people Israel.", "dra": "And when the prophet shall err, and speak a word: I the Lord have deceived that prophet: and I will stretch forth my hand upon him, and will cut him off from the midst of my people Israel.", "bbe": "And if the prophet, tricked by deceit, says anything, it is I the Lord by whom he has been tricked, and I will put out my hand against him, and he will be cut off from among my people Israel.", "geneva": "And if the Prophet be deceiued, when hee hath spoken a thing, I the Lord haue deceiued that Prophet, and I will stretch out mine hande vpon him, and will destroy him from the middes of my people of Israel.", "wycliffe": "And whanne a profete errith, and spekith a word, Y the Lord schal disseyue that profete; and Y schal stretche forth myn hond on hym, and Y schal do hym awei fro the myddis of my puple Israel.", "rotherham": "Yea the prophet himself when he suffereth himself to be deceived, and speaketh a word, I Yahweh, have suffered that prophet to be deceived, Then will I stretch forth my hand against him, and destroy him out of the midst of my people. Israel:", "darby": "And if the prophet be enticed and shall speak a word, I Jehovah have enticed that prophet; and I will stretch out my hand against him, and will destroy him from the midst of my people Israel.", "twenty": "", "jps": "And when the prophet is enticed and speaketh a word, I HaShem have enticed that prophet, and I will stretch out My hand upon him, and will destroy him from the midst of My people Israel.", "acv": "And if the prophet is deceived and speaks a word, I, Jehovah, have deceived that prophet. And I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.", "anderson": "", "haweis": "", "noyes": "And when the prophet is deceived when he speaketh anything, I, Jehovah, have deceived that prophet; and I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.", "webster": "And if the prophet be deceived when he hath spoken a thing, I the LORD have deceived that prophet, and I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.", "vulgate": "et propheta cum erraverit et locutus fuerit verbum ego Dominus decepi prophetam illum et extendam manum meam super eum et delebo eum de medio populi mei Israhel;", "brenton": "And if a prophet should cause to err and should speak, I the Lord have caused that prophet to err, and will stretch out my hand upon him, and will utterly destroy him from the midst of my people Israel."}}, {"v": 10, "ref": "14:10", "o": "וְ/נָשְׂא֖וּ עֲוֺנָ֑/ם כַּֽ/עֲוֺן֙ הַ/דֹּרֵ֔שׁ כַּ/עֲוֺ֥ן הַ/נָּבִ֖יא יִֽהְיֶֽה", "en": {"kjv": "And they shall bear the punishment of their iniquity: the punishment of the prophet shall be even as the punishment of him that seeketh unto him;", "web": "They shall bear their iniquity: the iniquity of the prophet shall be even as the iniquity of him who seeks him;", "bsb": "They will bear their punishment—the punishment of the inquirer will be the same as that of the prophet—", "asv": "And they shall bear their iniquity: the iniquity of the prophet shall be even as the iniquity of him that seeketh unto him;", "ylt": "And they have borne their iniquity: as the iniquity of the inquirer, so is the iniquity of the prophet;", "dra": "And they shall bear their iniquity: according to the iniquity of him that inquireth, so shall the iniquity of the prophet be.", "bbe": "And the punishment of their sin will be on them: the sin of the prophet will be the same as the sin of him who goes to him for directions;", "geneva": "And they shall beare their punishment: the punishment of the Prophet shall bee euen as the punishment of him that asketh,", "wycliffe": "And thei schulen bere her wickidnesse; bi the wickidnesse of the axere, so the wickidnesse of the profete schal be;", "rotherham": "So shall they bear their punishment, As the punishment of him that enquireth, So shall the punishment of the prophet be:", "darby": "And they shall bear their iniquity: the iniquity of the prophet shall be even as the iniquity of the inquirer;", "twenty": "", "jps": "And they shall bear their iniquity; the iniquity of the prophet shall be even as the iniquity of him that inquireth;", "acv": "And they shall bear their iniquity. The iniquity of the prophet shall be even as the iniquity of him who seeks him,", "anderson": "", "haweis": "", "noyes": "And they shall bear the punishment of their iniquity; the punishment of the prophet shall be even as the punishment of him that inquireth of him;", "webster": "And they shall bear the punishment of their iniquity: the punishment of the prophet shall be even as the punishment of him that seeketh [to him];", "vulgate": "et portabunt iniquitatem suam iuxta iniquitatem interrogantis sic iniquitas prophetae erit;", "brenton": "And they shall bear their iniquity according to the trespass of him that asks; and it shall be in like manner to the prophet according to the trespass:"}}, {"v": 11, "ref": "14:11", "o": "לְ֠מַעַן לֹֽא יִתְע֨וּ ע֤וֹד בֵּֽית יִשְׂרָאֵל֙ מֵ/אַֽחֲרַ֔/י וְ/לֹֽא יִטַּמְּא֥וּ ע֖וֹד בְּ/כָל פִּשְׁעֵי/הֶ֑ם וְ/הָ֥יוּ לִ֣/י לְ/עָ֗ם וַֽ/אֲנִי֙ אֶהְיֶ֤ה לָ/הֶם֙ לֵֽ/אלֹהִ֔ים נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "That the house of Israel may go no more astray from me, neither be polluted any more with all their transgressions; but that they may be my people, and I may be their God, saith the Lord God.", "web": "that the house of Israel may go no more astray from me, neither defile themselves any more with all their transgressions; but that they may be my people, and I may be their God, says the Lord Yahweh.", "bsb": "in order that the house of Israel may no longer stray from Me and no longer defile themselves with all their transgressions. Then they will be My people and I will be their God, declares the Lord GOD.’”", "asv": "that the house of Israel may go no more astray from me, neither defile themselves any more with all their transgressions; but that they may be my people, and I may be their God, saith the Lord Jehovah.", "ylt": "so that the house of Israel do not wander any more from after Me, nor are defiled any more with all their transgressions, and they have been to Me for a people, and I am to them for God--an affirmation of the Lord Jehovah.'", "dra": "That the house of Israel may go no more astray from me, nor be polluted with all their transgressions: but may be my people, and I may be their God, saith the Lord of hosts.", "bbe": "So that the children of Israel may no longer go wandering away from me, or make themselves unclean with all their wrongdoing; but they will be my people, and I will be their God, says the Lord.", "geneva": "That the house of Israel may go no more astray from mee, neither bee polluted any more with all their transgressions, but that they may be my people, and I may be their God, sayth the Lord God.", "wycliffe": "that the hous of Israel erre no more fro me, nether be defoulid in alle her trespassyngis; but that it be in to a puple to me, and Y be in to a God to hem, seith the Lord of oostis.", "rotherham": "That the house of Israel may no more go astray from following me, And no more defile themselves by any of their transgressions,— But may become my people, and I, may become their God, Declareth My Lord Yahweh.", "darby": "that the house of Israel may go no more astray from me, neither make themselves any more unclean with all their transgressions; and they shall be my people, and I will be theirGod, saith the Lord Jehovah.", "twenty": "", "jps": "that the house of Israel may go no more astray from Me, neither defile themselves any more with all their transgressions; but that they may be My people, and I may be their G-d, saith the L-rd GOD.'", "acv": "that the house of Israel may no more go astray from me, nor defile themselves any more with all their transgressions, but that they may be my people, and I may be their God, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "that the house of Israel may no more go astray from me, nor be polluted any more with all their transgressions; but that they may be my people, and I may be their God, saith the Lord Jehovah.", "webster": "That the house of Israel may no more go astray from me, neither be polluted any more with all their transgressions; but that they may be my people, and I may be their God, saith the Lord GOD.", "vulgate": "ut non erret ultra domus Israhel a me neque polluatur in universis praevaricationibus suis sed sit mihi in populum et ego sim eis in Deum ait Dominus exercituum;", "brenton": "that the house of Israel may no more go astray from me, and that they may no more defile themselves with any of their transgressions: so shall they be my people, and I will be their God, saith the Lord."}}, {"v": 12, "ref": "14:12", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again to me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "The worde of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Again the word of Jehovah came to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 13, "ref": "14:13", "o": "בֶּן אָדָ֗ם אֶ֚רֶץ כִּ֤י תֶחֱטָא לִ/י֙ לִ/מְעָל מַ֔עַל וְ/נָטִ֤יתִי יָדִ/י֙ עָלֶ֔י/הָ וְ/שָׁבַ֥רְתִּי לָ֖/הּ מַטֵּה לָ֑חֶם וְ/הִשְׁלַחְתִּי בָ֣/הּ רָעָ֔ב וְ/הִכְרַתִּ֥י מִמֶּ֖/נָּה אָדָ֥ם וּ/בְהֵמָֽה", "en": {"kjv": "Son of man, when the land sinneth against me by trespassing grievously, then will I stretch out mine hand upon it, and will break the staff of the bread thereof, and will send famine upon it, and will cut off man and beast from it:", "web": "Son of man, when a land sins against me by committing a trespass, and I stretch out my hand on it, and break the staff of its bread, and send famine on it, and cut off from it man and animal;", "bsb": "“Son of man, if a land sins against Me by acting unfaithfully, and I stretch out My hand against it to cut off its supply of food, to send famine upon it, and to cut off from it both man and beast,", "asv": "Son of man, when a land sinneth against me by committing a trespass, and I stretch out my hand upon it, and break the staff of the bread thereof, and send famine upon it, and cut off from it man and beast;", "ylt": "`Son of man, the land--when it sinneth against Me to commit a trespass, and I have stretched out My hand against it, and broken for it the staff of bread, and sent into it famine, and cut off from it man and beast--", "dra": "Son of man, when a land shall sin against me, so as to transgress grievously, I will stretch forth my hand upon it, and will break the staff of the bread thereof: and I will send famine upon it, and will destroy man and beast out of it.", "bbe": "Son of man, when a land, sinning against me, does wrong, and my hand is stretched out against it, and the support of its bread is broken, and I make it short of food, cutting off man and beast from it:", "geneva": "Sonne of man, when ye land sinneth against me by committing a trespasse, then will I stretch out mine hand vpon it, and will breake the staffe of the bread thereof, and will send famine vpon it, and I will destroy man and beast forth of it.", "wycliffe": "Sone of man, whanne the lond synneth ayens me, that it trespassynge do trespas, Y schal stretche forth myn hond on it, and Y schal al to-breke the yerde of breed therof; and Y schal sende hungur in to it, and Y schal sle of it man and beeste.", "rotherham": "Son of man, When a land, shall sin against me by committing treachery, and I shall stretch out my hand against it, And break for it the staff of bread, And send thereon famine, And cut off therefrom man and beast,", "darby": "Son of man, when a land sinneth against me by working unfaithfulness, and I stretch out my hand upon it, and break the staff of the bread thereof, and send famine upon it, and cut off man and beast from it;", "twenty": "", "jps": "'Son of man, when a land sinneth against Me by trespassing grievously, and I stretch out My hand upon it, and break the staff of the bread thereof, and send famine upon it, and cut off from it man and beast;", "acv": "Son of man, when a land sins against me by committing a trespass, and I stretch out my hand upon it, and break the staff of the bread thereof, and send famine upon it, and cut off from it man and beast,", "anderson": "", "haweis": "", "noyes": "Son of man, when a land sinneth against me, and grievously transgresseth, and I stretch out my hand against it, and break the staff of its bread, and send famine upon it, and cut off from it man and beast,", "webster": "Son of man, when the land sinneth against me by trespassing grievously, then will I stretch out my hand upon it, and will break the staff of the bread thereof, and will send famine upon it, and will cut off man and beast from it:", "vulgate": "fili hominis terra cum peccaverit mihi ut praevaricetur praevaricans extendam manum meam super eam et conteram virgam panis eius et inmittam in eam famem et interficiam de ea hominem et iumentum;", "brenton": "Son of man, if a land shall sin against me by committing a trespass, then will I stretch out my hand upon it, and will break its staff of bread, and will send forth famine upon it, and cut off from it man and beast."}}, {"v": 14, "ref": "14:14", "o": "וְ֠/הָיוּ שְׁלֹ֨שֶׁת הָ/אֲנָשִׁ֤ים הָ/אֵ֨לֶּה֙ בְּ/תוֹכָ֔/הּ נֹ֖חַ דנאל דָּנִיֵּ֣אל וְ/אִיּ֑וֹב הֵ֤מָּה בְ/צִדְקָתָ/ם֙ יְנַצְּל֣וּ נַפְשָׁ֔/ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Though these three men, Noah, Daniel, and Job, were in it, they should deliver but their own souls by their righteousness, saith the Lord God.", "web": "though these three men, Noah, Daniel, and Job, were in it, they should deliver but their own souls by their righteousness, says the Lord Yahweh.", "bsb": "then even if these three men—Noah, Daniel, and Job—were in it, their righteousness could deliver only themselves, declares the Lord GOD.", "asv": "though these three men, Noah, Daniel, and Job, were in it, they should deliver but their own souls by their righteousness, saith the Lord Jehovah.", "ylt": "and these three men have been in its midst, Noah, Daniel, and Job--they by their righteousness deliver their own soul--an affirmation of the Lord Jehovah.", "dra": "And if these three men, Noe, Daniel, and Job, shall be in it: they shall deliver their own souls by their justice, saith the Lord of hosts.", "bbe": "Even if these three men, Noah, Daniel, and Job, were in it, only themselves would they keep safe by their righteousness, says the Lord.", "geneva": "Though these three men Noah, Daniel, and Iob were among them, they shoulde deliuer but their owne soules by their righteousnes, saith the Lord God.", "wycliffe": "And if these thre men Noe, Danyel, and Job, ben in the myddis therof, thei bi her riytfulnesse schulen delyuere her soulis, seith the Lord of oostis.", "rotherham": "Then should these three men be in the midst thereof, Noah, Daniel, and Job, they by their righteousness should deliver their own lives— Declareth My Lord, Yahweh.", "darby": "though these three men, Noah, Daniel, and Job, should be in it, they should deliver [but] their own souls by their righteousness, saith the Lord Jehovah.", "twenty": "", "jps": "though these three men, Noah, Daniel, and Job, were in it, they should deliver but their own souls by their righteousness, saith the L-rd GOD.", "acv": "though these three men, Noah, Daniel, and Job, were in it, they would deliver but their own souls by their righteousness, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "though these three men were in it, Noah, Daniel, and Job, they should deliver only themselves by their righteousness, saith the Lord Jehovah.", "webster": "Though these three men, Noah, Daniel, and Job, were in it, they should deliver their own souls only by their righteousness, saith the Lord GOD.", "vulgate": "et si fuerint tres viri isti in medio eius Noe Danihel et Iob ipsi iustitia sua liberabunt animas suas ait Dominus exercituum;", "brenton": "And though these three men should be in the midst of it, Noe, and Daniel, and Job, they alone should be delivered by their righteousness, saith the Lord."}}, {"v": 15, "ref": "14:15", "o": "לֽוּ חַיָּ֥ה רָעָ֛ה אַעֲבִ֥יר בָּ/אָ֖רֶץ וְ/שִׁכְּלָ֑תָּ/ה וְ/הָיְתָ֤ה שְׁמָמָה֙ מִ/בְּלִ֣י עוֹבֵ֔ר מִ/פְּנֵ֖י הַ/חַיָּֽה", "en": {"kjv": "If I cause noisome beasts to pass through the land, and they spoil it, so that it be desolate, that no man may pass through because of the beasts:", "web": "If I cause evil animals to pass through the land, and they ravage it, and it be made desolate, so that no man may pass through because of the animals;", "bsb": "Or if I send wild beasts through the land to leave it childless and desolate, with no man passing through it for fear of the beasts,", "asv": "If I cause evil beasts to pass through the land, and they ravage it, and it be made desolate, so that no man may pass through because of the beasts;", "ylt": "`If an evil beast I cause to pass through the land, and it hath bereaved, and it hath been a desolation, without any passing through because of the beast--", "dra": "And if I shall bring mischievous beasts also upon the land to waste it, and it be desolate, so that there is none that can pass because of the beasts:", "bbe": "Or if I send evil beasts through the land causing destruction and making it waste, so that no man may go through because of the beasts:", "geneva": "If I bring noysome beastes into the lande and they spoyle it, so that it bee desolate, that no man may passe through, because of beastes,", "wycliffe": "That if also Y brynge in worste beestis on the lond, that Y distrie it, and if it is with out weie, for that no passer is for the beestis,", "rotherham": "If a mischievous wild beast, I suffer to pass through the land, and that beast bereave it, so that it become too desolate for any man to pass through, by reason of the wild beast,", "darby": "If I cause evil beasts to pass through the land, and they bereave it, and it become a desolation, so that no one passeth through because of the beasts;", "twenty": "", "jps": "If I cause evil beasts to pass through the land, and they bereave it, and it be desolate, so that no man may pass through because of the beasts;", "acv": "If I cause evil beasts to pass through the land, and they ravage it, and it be made desolate, so that no man may pass through because of the beasts,", "anderson": "", "haweis": "", "noyes": "When I cause wild beasts to pass through the land, and they spoil it, and it be desolate so that none passeth through it because of the beasts,", "webster": "If I cause noisome beasts to pass through the land, and they lay it waste, so that it be desolate, that no man may pass through because of the beasts:", "vulgate": "quod si et bestias pessimas induxero super terram ut vastem eam et fuerit invia eo quod non sit pertransiens propter bestias;", "brenton": "If again I bring evil beasts upon the land, and take vengeance upon it, and it be ruined, and there be no one to pass through for fear of the wild beasts:"}}, {"v": 16, "ref": "14:16", "o": "שְׁלֹ֨שֶׁת הָ/אֲנָשִׁ֣ים הָ/אֵלֶּה֮ בְּ/תוֹכָ/הּ֒ חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה אִם בָּנִ֥ים וְ/אִם בָּנ֖וֹת יַצִּ֑ילוּ הֵ֤מָּה לְ/בַדָּ/ם֙ יִנָּצֵ֔לוּ וְ/הָ/אָ֖רֶץ תִּהְיֶ֥ה שְׁמָמָֽה", "en": {"kjv": "Though these three men were in it, as I live, saith the Lord God, they shall deliver neither sons nor daughters; they only shall be delivered, but the land shall be desolate.", "web": "though these three men were in it, as I live, says the Lord Yahweh, they should deliver neither sons nor daughters; they only should be delivered, but the land should be desolate.", "bsb": "then as surely as I live, declares the Lord GOD, even if these three men were in it, they could not deliver their own sons or daughters. They alone would be delivered, but the land would be desolate.", "asv": "though these three men were in it, as I live, saith the Lord Jehovah, they should deliver neither sons nor daughters; they only should be delivered, but the land should be desolate.", "ylt": "these three men in its midst: I live--an affirmation of the Lord Jehovah--neither sons nor daughters do they deliver; they alone are delivered, and the land is a desolation.", "dra": "If these three men shall be in it, as I live, saith the Lord, they shall deliver neither sons nor daughters: but they only shall be delivered, and the land shall be made desolate.", "bbe": "Even if these three men were in it, by my life, says the Lord, they would not keep safe their sons or daughters, but only themselves, and the land would be made waste.", "geneva": "Though these three men were in the mids thereof, As I liue, sayth the Lord God, they shall saue neither sonnes nor daughters: they onely shalbe deliuered, but the land shall be waste.", "wycliffe": "and these thre men, that `ben bifore seid, ben therynne, Y lyue, seith the Lord God, for thei schulen nethir delyuere sones, nether douytris, but thei aloone schulen be deliuered; forsothe the lond schal be maad desolat.", "rotherham": "[Were] these three men in the midst thereof, As I live, Declareth My Lord Yahweh, Surely neither sons nor daughters, should they deliver, They alone should be delivered, But the land, should become a desolation.", "darby": "— though these three men should be in it, [as] I live, saith the Lord Jehovah, they should deliver neither sons nor daughters: they only should be delivered, and the land should be a desolation.", "twenty": "", "jps": "though these three men were in it, as I live, saith the L-rd GOD, they shall deliver neither sons nor daughters; they only shall be delivered, but the land shall be desolate.", "acv": "though these three men were in it, as I live, says the lord Jehovah, they would deliver neither sons nor daughters, they only would be delivered, but the land would be desolate.", "anderson": "", "haweis": "", "noyes": "though these three men were in it, as I live, saith the Lord Jehovah, they should deliver neither sons nor daughters; they only should be delivered, but the land should be desolate.", "webster": "[Though] these three men [were] in it, [as] I live, saith the Lord GOD, they shall deliver neither sons nor daughters; they only shall be delivered, but the land shall be desolate.", "vulgate": "tres viri isti qui fuerint in ea vivo ego dicit Dominus Deus quia nec filios nec filias liberabunt sed ipsi soli liberabuntur terra autem desolabitur;", "brenton": "and if these three men should be in the midst of it, as I live, saith the Lord, neither sons nor daughters shall be saved, but these only shall be saved, and the land shall be destroyed."}}, {"v": 17, "ref": "14:17", "o": "א֛וֹ חֶ֥רֶב אָבִ֖יא עַל הָ/אָ֣רֶץ הַ/הִ֑יא וְ/אָמַרְתִּ֗י חֶ֚רֶב תַּעֲבֹ֣ר בָּ/אָ֔רֶץ וְ/הִכְרַתִּ֥י מִמֶּ֖/נָּה אָדָ֥ם וּ/בְהֵמָֽה", "en": {"kjv": "Or if I bring a sword upon that land, and say, Sword, go through the land; so that I cut off man and beast from it:", "web": "Or if I bring a sword on that land, and say, Sword, go through the land; so that I cut off from it man and animal;", "bsb": "Or if I bring a sword against that land and say, ‘Let a sword pass through it,’ so that I cut off from it both man and beast,", "asv": "Or if I bring a sword upon that land, and say, Sword, go through the land; so that I cut off from it man and beast;", "ylt": "`Or--a sword I bring in against that land, and I have said: Sword, thou dost pass over through the land, and I have cut off from it man and beast--", "dra": "Or if I bring the sword upon that land, and say to the sword: Pass through the land: and I destroy man and beast out of it:", "bbe": "Or if I send a sword against that land, and say, Sword, go through the land, cutting off from it man and beast:", "geneva": "Or if I bring a sworde vpon this land, and say, Sword, go through the land, so that I destroy man and beast out of it,", "wycliffe": "Ethir if Y brynge in swerd on that lond, and Y seie to the swerd, Passe thou thorouy the lond, and Y sle of it man and beeste,", "rotherham": "Or, a sword, I should bring upon that land, and should say. O sword! thou shalt go through the land, and so I should cut off therefrom, man and beast,", "darby": "Or [if] I bring the sword upon that land, and say, Sword, go through the land, so that I cut off man and beast from it,", "twenty": "", "jps": "Or if I bring a sword upon that land, and say: Let the sword go through the land, so that I cut off from it man and beast;", "acv": "Or if I bring a sword upon that land, and say, Sword, go through the land, so that I cut off from it man and beast,", "anderson": "", "haweis": "", "noyes": "Or when I bring a sword upon that land, and say, Sword, go through the land so that I cut off from it man and beast,", "webster": "Or [if] I bring a sword upon that land, and say, Sword, go through the land; so that I cut off man and beast from it:", "vulgate": "vel si gladium induxero super terram illam et dixero gladio transi per terram et interfecero de ea hominem et iumentum;", "brenton": "Or again if I bring a sword upon that land, and say, Let the sword go through the land; and I cut off from them man and beast:"}}, {"v": 18, "ref": "14:18", "o": "וּ/שְׁלֹ֨שֶׁת הָ/אֲנָשִׁ֣ים הָ/אֵלֶּה֮ בְּ/תוֹכָ/הּ֒ חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה לֹ֥א יַצִּ֖ילוּ בָּנִ֣ים וּ/בָנ֑וֹת כִּ֛י הֵ֥ם לְ/בַדָּ֖/ם יִנָּצֵֽלוּ", "en": {"kjv": "Though these three men were in it, as I live, saith the Lord God, they shall deliver neither sons nor daughters, but they only shall be delivered themselves.", "web": "though these three men were in it, as I live, says the Lord Yahweh, they should deliver neither sons nor daughters, but they only should be delivered themselves.", "bsb": "then as surely as I live, declares the Lord GOD, even if these three men were in it, they could not deliver their own sons or daughters. They alone would be delivered.", "asv": "though these three men were in it, as I live, saith the Lord Jehovah, they should deliver neither sons nor daughters, but they only should be delivered themselves.", "ylt": "and these three men in its midst: I live--an affirmation of the Lord Jehovah--they deliver not sons and daughters, for they alone are delivered.", "dra": "And these three men be in the midst thereof: as I live, saith the Lord God, they shall deliver neither sons nor daughters, but they themselves alone shall be delivered.", "bbe": "Even if these three men were in it, by my life, says the Lord, they would not keep safe their sons or daughters, but only themselves.", "geneva": "Though these three men were in the mids thereof, As I liue, sayth the Lord God, they shall deliuer neither sonnes nor daughters, but they onely shall be deliuered themselues.", "wycliffe": "and these thre men ben in the myddis therof, Y lyue, seith the Lord God, that thei schulen not delyuere sones nether douytris, but thei aloone schulen be delyuered.", "rotherham": "Were these three men in the midst thereof, As I live! Saith My Lord Yahweh, They should deliver neither sons nor daughters,— For they alone, should be delivered.", "darby": "and these three men should be in it, [as] I live, saith the Lord Jehovah, they should deliver neither sons nor daughters, but they only themselves should be delivered.", "twenty": "", "jps": "though these three men were in it, as I live, saith the L-rd GOD, they shall deliver neither sons nor daughters, but they only shall be delivered themselves.", "acv": "though these three men were in it, as I live, says the lord Jehovah, they would deliver neither sons nor daughters, but they only would be delivered themselves.", "anderson": "", "haweis": "", "noyes": "though these three men were in it, as I live, saith the Lord Jehovah, they should deliver neither sons nor daughters, but they only should be delivered themselves.", "webster": "Though these three men [were] in it, [as] I live, saith the Lord GOD, they shall deliver neither sons nor daughters, but they only shall be delivered themselves.", "vulgate": "et tres viri isti fuerint in medio eius vivo ego dicit Dominus Deus non liberabunt filios neque filias sed ipsi soli liberabuntur;", "brenton": "though these three men were in the midst of it, as I live, saith the Lord, they shall not deliver sons or daughters, but they only shall be saved themselves."}}, {"v": 19, "ref": "14:19", "o": "א֛וֹ דֶּ֥בֶר אֲשַׁלַּ֖ח אֶל הָ/אָ֣רֶץ הַ/הִ֑יא וְ/שָׁפַכְתִּ֨י חֲמָתִ֤/י עָלֶ֨י/הָ֙ בְּ/דָ֔ם לְ/הַכְרִ֥ית מִמֶּ֖/נָּה אָדָ֥ם וּ/בְהֵמָֽה", "en": {"kjv": "Or if I send a pestilence into that land, and pour out my fury upon it in blood, to cut off from it man and beast:", "web": "Or if I send a pestilence into that land, and pour out my wrath on it in blood, to cut off from it man and animal;", "bsb": "Or if I send a plague into that land and pour out My wrath upon it through bloodshed, cutting off from it both man and beast,", "asv": "Or if I send a pestilence into that land, and pour out my wrath upon it in blood, to cut off from it man and beast;", "ylt": "`Or--pestilence I send unto that land, and I have poured out My fury against it in blood, to cut off from it man and beast--", "dra": "Or if I also send the pestilence upon that land, and pour out my indignation upon it in blood, to cut off from it man and beast:", "bbe": "Or if I send disease into that land, letting loose my wrath on it in blood, cutting off from it man and beast:", "geneva": "Or if I send a pestilence into this land, and powre out my wrath vpon it in blood, to destroy out of it man and beast,", "wycliffe": "Forsothe if Y brynge in also pestilence on that lond, and Y schede out myn indignacioun on it in blood, that Y do awei fro it man and beeste,", "rotherham": "Or pestilence, I, should send into that land,—and should pour out mine indignation thereon in blood, to cut off therefrom man and beast", "darby": "Or [if] I send a pestilence into that land, and pour out my fury upon it in blood, to cut off from it man and beast,", "twenty": "", "jps": "Or if I send a pestilence into that land, and pour out My fury upon it in blood, to cut off from it man and beast;", "acv": "Or if I send a pestilence into that land, and pour out my wrath upon it in blood, to cut off from it man and beast,", "anderson": "", "haweis": "", "noyes": "Or when I send a pestilence upon that land, and pour out my fury upon it in blood, to cut off from it man and beast,", "webster": "Or [if] I send a pestilence into that land, and pour out my fury upon it in blood, to cut off from it man and beast:", "vulgate": "si autem et pestilentiam inmisero super terram illam et effudero indignationem meam super eam in sanguine ut auferam ex ea hominem et iumentum;", "brenton": "Or if again I send pestilence upon that land, and pour out my wrath upon it in blood, to destroy from off it man and beast:"}}, {"v": 20, "ref": "14:20", "o": "וְ/נֹ֨חַ דנאל דָּנִיֵּ֣אל וְ/אִיּוֹב֮ בְּ/תוֹכָ/הּ֒ חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה אִם בֵּ֥ן אִם בַּ֖ת יַצִּ֑ילוּ הֵ֥מָּה בְ/צִדְקָתָ֖/ם יַצִּ֥ילוּ נַפְשָֽׁ/ם", "en": {"kjv": "Though Noah, Daniel, and Job, were in it, as I live, saith the Lord God, they shall deliver neither son nor daughter; they shall but deliver their own souls by their righteousness.", "web": "though Noah, Daniel, and Job, were in it, as I live, says the Lord Yahweh, they should deliver neither son nor daughter; they should but deliver their own souls by their righteousness.", "bsb": "then as surely as I live, declares the Lord GOD, even if Noah, Daniel, and Job were in it, they could not deliver their own sons or daughters. Their righteousness could deliver only themselves.", "asv": "though Noah, Daniel, and Job, were in it, as I live, saith the Lord Jehovah, they should deliver neither son nor daughter; they should but deliver their own souls by their righteousness.", "ylt": "and Noah, Daniel, and Job, in its midst: I live--an affirmation of the Lord Jehovah--neither son nor daughter do they deliver; they, by their righteousness, deliver their own soul.", "dra": "And Noe, and Daniel, and Job be in the midst thereof: as I live, saith the Lord God, they shall deliver neither son nor daughter: but they shall only deliver their own souls by their justice.", "bbe": "Even if Noah, Daniel, and Job were in it, by my life, says the Lord, they would not keep son or daughter safe; only themselves would they keep safe through their righteousness.", "geneva": "And though Noah, Daniel and Iob were in the middes of it, As I liue, sayth the Lord God, they shall deliuer neither sonne nor daughter: they shall but deliuer their owne soules by their righteousnes.", "wycliffe": "and Noe, and Danyel, and Joob, ben in the myddis therof, Y lyue, seith the Lord God, for thei schulen not delyuere a sone and a douyter, but thei bi her riytfulnesse schulen delyuere her soulis.", "rotherham": "Were Noah, Daniel and Job in the midst thereof, As I live, Declareth My Lord Yahweh, Surely neither son nor daughter, should they deliver, They, by their righteousness should deliver only their own lives.", "darby": "and Noah, Daniel, and Job should be in it, [as] I live, saith the Lord Jehovah, they should deliver neither son nor daughter: they should [but] deliver their own souls by their righteousness.", "twenty": "", "jps": "though Noah, Daniel, and Job, were in it, as I live, saith the L-rd GOD, they shall deliver neither son nor daughter; they shall but deliver their own souls by their righteousness.", "acv": "though Noah, Daniel, and Job, were in it, as I live, says the lord Jehovah, they would deliver neither son nor daughter, they would but deliver their own souls by their righteousness.", "anderson": "", "haweis": "", "noyes": "though Noah, Daniel, and Job were in it, as I live, saith the Lord Jehovah, they should deliver neither son nor daughter; they should deliver only themselves by their righteousness.", "webster": "Though Noah, Daniel, and Job, [were] in it, [as] I live, saith the Lord GOD, they shall deliver neither son nor daughter; they shall deliver their own souls only by their righteousness.", "vulgate": "et Noe et Danihel et Iob fuerint in medio eius vivo ego dicit Dominus Deus quia filium et filiam non liberabunt sed ipsi iustitia sua liberabunt animas suas;", "brenton": "and should Noe, and Daniel, and Job, be in the midst of it, as I live, saith the Lord, there shall be left them neither sons nor daughters; only they by their righteousness shall deliver their souls."}}, {"v": 21, "ref": "14:21", "o": "כִּי֩ כֹ֨ה אָמַ֜ר אֲדֹנָ֣/י יְהֹוִ֗ה אַ֣ף כִּֽי אַרְבַּ֣עַת שְׁפָטַ֣/י הָ/רָעִ֡ים חֶ֠רֶב וְ/רָעָ֞ב וְ/חַיָּ֤ה רָעָה֙ וָ/דֶ֔בֶר שִׁלַּ֖חְתִּי אֶל יְרוּשָׁלִָ֑ם לְ/הַכְרִ֥ית מִמֶּ֖/נָּה אָדָ֥ם וּ/בְהֵמָֽה", "en": {"kjv": "For thus saith the Lord God; How much more when I send my four sore judgments upon Jerusalem, the sword, and the famine, and the noisome beast, and the pestilence, to cut off from it man and beast?", "web": "For thus says the Lord Yahweh: How much more when I send my four severe judgments on Jerusalem, the sword, and the famine, and the evil animals, and the pestilence, to cut off from it man and animal!", "bsb": "For this is what the Lord GOD says: ‘How much worse will it be when I send against Jerusalem My four dire judgments—sword, famine, wild beasts, and plague—in order to cut off from it both man and beast?", "asv": "For thus saith the Lord Jehovah: How much more when I send my four sore judgments upon Jerusalem, the sword, and the famine, and the evil beasts, and the pestilence, to cut off from it man and beast!", "ylt": "`For thus said the Lord Jehovah: Although My four sore judgments--sword, and famine, and wild beast, and pestilence--I have sent unto Jerusalem, to cut off from it man and beast,", "dra": "For thus saith the Lord: Although I shall send in upon Jerusalem my four grievous judgments, the sword, and the famine, and the mischievous beasts, and the pestilence, to destroy out of it man and beast,", "bbe": "For this is what the Lord has said: How much more when I send my four bitter punishments on Jerusalem, the sword and need of food and evil beasts and disease, cutting off from it man and beast?", "geneva": "For thus saith the Lord God, Howe much more when I sende my foure sore iudgements vpon Ierusalem, euen the sworde, and famine, and the noysome beast and pestilence, to destroy man and beast out of it?", "wycliffe": "For the Lord God seith these thingis, That thouy Y sende in my foure worste domes, swerd, and hungur, and yuele beestis, and pestilence, in to Jerusalem, that Y sle of it man and beeste,", "rotherham": "For thus, saith My Lord Yahweh, How much less [should they avail] when my four calamitous judgments, sword and famine and mischievous wild beast and pestilence I have sent against Jerusalem,—to cut off therefrom man and beast?", "darby": "For thus saith the Lord Jehovah: How much more when I send my four sore judgments upon Jerusalem, the sword, and the famine, and the evil beast, and the pestilence, to cut off from it man and beast!", "twenty": "", "jps": "For thus saith the L-rd GOD: How much more when I send My four sore judgments against Jerusalem, the sword, and the famine, and the evil beasts, and the pestilence, to cut off from it man and beast.", "acv": "For thus says the lord Jehovah: How much more when I send my four severe judgments upon Jerusalem, the sword, and the famine, and the evil beasts, and the pestilence, to cut off from it man and beast!", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: How much more, when I send my four grievous judgments against Jerusalem, the sword, and the famine, and the wild beast, and the pestilence, to cut off from it man and beast?", "webster": "For thus saith the Lord GOD; How much more when I send my four severe judgments upon Jerusalem, the sword, and the famine, and the noisome beast, and the pestilence, to cut off from it man and beast?", "vulgate": "quoniam haec dicit Dominus Deus quod si et quattuor iudicia mea pessima gladium et famem et bestias malas et pestilentiam misero in Hierusalem ut interficiam de ea hominem et pecus;", "brenton": "Thus saith the Lord, And if I even send upon Jerusalem my four sore judgments, sword, and famine, and evil beasts, and pestilence, to destroy from out of it man and beast;"}}, {"v": 22, "ref": "14:22", "o": "וְ/הִנֵּ֨ה נֽוֹתְרָה בָּ֜/הּ פְּלֵטָ֗ה הַֽ/מּוּצָאִים֮ בָּנִ֣ים וּ/בָנוֹת֒ הִנָּ/ם֙ יוֹצְאִ֣ים אֲלֵי/כֶ֔ם וּ/רְאִיתֶ֥ם אֶת דַּרְכָּ֖/ם וְ/אֶת עֲלִֽילוֹתָ֑/ם וְ/נִחַמְתֶּ֗ם עַל הָֽ/רָעָה֙ אֲשֶׁ֤ר הֵבֵ֨אתִי֙ עַל יְר֣וּשָׁלִַ֔ם אֵ֛ת כָּל אֲשֶׁ֥ר הֵבֵ֖אתִי עָלֶֽי/הָ", "en": {"kjv": "Yet, behold, therein shall be left a remnant that shall be brought forth, both sons and daughters: behold, they shall come forth unto you, and ye shall see their way and their doings: and ye shall be comforted concerning the evil that I have brought upon Jerusalem, even concerning all that I have brought upon it.", "web": "Yet, behold, therein shall be left a remnant that shall be carried out, both sons and daughters: behold, they shall come out to you, and you shall see their way and their doings; and you shall be comforted concerning the evil that I have brought on Jerusalem, even concerning all that I have brought on it.", "bsb": "Yet, behold, some survivors will be left in it—sons and daughters who will be brought out. They will come out to you, and when you see their conduct and actions, you will be comforted regarding the disaster I have brought upon Jerusalem—all that I have brought upon it.", "asv": "Yet, behold, therein shall be left a remnant that shall be carried forth, both sons and daughters: behold, they shall come forth unto you, and ye shall see their way and their doings; and ye shall be comforted concerning the evil that I have brought upon Jerusalem, even concerning all that I have brought upon it.", "ylt": "yet, lo, there hath been left in it an escape, who are brought forth, sons and daughters, lo, they are coming forth unto you, and ye have seen their way, and their doings, and have been comforted concerning the evil that I have brought in against Jerusalem, all that which I have brought in against it.", "dra": "Yet there shall be left in it some that shall be saved, who shall bring away their sons and daughters: behold they shall come among you, and you shall see their way, and their doings: and you shall be comforted concerning the evil that I have brought upon Jerusalem, in all things that I have brought upon it.", "bbe": "But truly, there will still be a small band who will be safe, even sons and daughters: and they will come out to you, and you will see their ways and their doings: and you will be comforted about the evil which I have sent on Jerusalem, even about everything I have sent on it.", "geneva": "Yet beholde, therein shalbe left a remnant of them that shalbe caryed away both sonnes and daughters: behold, they shall come forth vnto you, and ye shall see their way, and their enterprises: and ye shall be comforted, concerning the euill that I haue brought vpon Ierusalem, euen concerning al that I haue brought vpon it.", "wycliffe": "netheles saluacioun of hem that leden out sones and douytris, schal be left ther ynne. Lo! thei schulen go out to you, and ye schulen se the weie of hem, and the fyndyngis of hem; and ye schulen be coumfortid on the yuel, which Y brouyte in on Jerusalem, in alle thingis whiche Y bar in on it.", "rotherham": "Yet lo! there hath been left therein a remnant of fugitives to be brought forth —sons and daughters— There they are! coming forth unto you, And so ye shall see their way, and their doings, and be consoled over the calamity which I have brought in upon Jerusalem even all that I have brought in upon her.", "darby": "But behold, there shall be left in it those that escape, who shall be brought out of [it], sons and daughters. Behold, they shall come forth unto you, and ye shall see their way and their doings; and ye shall be comforted concerning the evil that I have brought upon Jerusalem, as to all that I have brought upon it.", "twenty": "", "jps": "And, behold, though there be left a remnant therein that shall be brought forth, both sons and daughters; behold, when they come forth unto you, and ye see their way and their doings, then ye shall be comforted concerning the evil that I have brought upon Jerusalem, even concerning all that I have brought upon it;", "acv": "Yet, behold, there shall be left a remnant in it that shall be carried forth, both sons and daughters. Behold, they shall come forth to you, and ye shall see their way and their doings. And ye shall be comforted concerning the evil that I have brought upon Jerusalem, even concerning all that I have brought upon it.", "anderson": "", "haweis": "", "noyes": "Yet behold, therein shall be left a remnant that shall be brought forth, sons and daughters. Behold, they shall come forth to you, and ye shall see their way and their doings, and ye shall be comforted concerning the evil which I have brought upon Jerusalem, even concerning all which I have brought upon her.", "webster": "Yet behold, therein shall be left a remnant that shall be brought forth, [both] sons and daughters: behold, they shall come forth to you, and ye shall see their way and their doings: and ye shall be comforted concerning the evil that I have brought upon Jerusalem, [even] concerning all that I have brought upon it.", "vulgate": "tamen relinquetur in ea salvatio educentium filios et filias ecce ipsi egredientur ad vos et videbitis viam eorum et adinventiones eorum et consolabimini super malo quod induxi in Hierusalem in omnibus quae inportavi super eam;", "brenton": "yet, behold, there shall be men left in it, the escaped thereof, who shall lead forth of it sons and daughters: behold, they shall go forth to you, and ye shall see their ways and their thoughts: and ye shall mourn over the evils which I have brought upon Jerusalem, even all the evils which I have brought upon it."}}, {"v": 23, "ref": "14:23", "o": "וְ/נִחֲמ֣וּ אֶתְ/כֶ֔ם כִּֽי תִרְא֥וּ אֶת דַּרְכָּ֖/ם וְ/אֶת עֲלִֽילוֹתָ֑/ם וִֽ/ידַעְתֶּ֗ם כִּי֩ לֹ֨א חִנָּ֤ם עָשִׂ֨יתִי֙ אֵ֣ת כָּל אֲשֶׁר עָשִׂ֣יתִי בָ֔/הּ נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "And they shall comfort you, when ye see their ways and their doings: and ye shall know that I have not done without cause all that I have done in it, saith the Lord God.", "web": "They shall comfort you, when you see their way and their doings; and you shall know that I have not done without cause all that I have done in it, says the Lord Yahweh.", "bsb": "They will bring you consolation when you see their conduct and actions, and you will know that it was not without cause that I have done all these things within it,’ declares the Lord GOD.”", "asv": "And they shall comfort you, when ye see their way and their doings; and ye shall know that I have not done without cause all that I have done in it, saith the Lord Jehovah.", "ylt": "And they have comforted you, for ye see their way and their doings, and ye have known that not for nought have I done all that which I have done in her--an affirmation of the Lord Jehovah.'", "dra": "And they shall comfort you, when you shall see their ways, and their doings: and you shall know that I have not done without cause all that I have done in it, saith the Lord God.", "bbe": "They will give you comfort when you see their ways and their doings: and you will be certain that not for nothing have I done all the things I have done in it, says the Lord.", "geneva": "And they shall comfort you, when yee see their way and their enterprises: and ye shall know, that I haue not done without cause all that I haue done in it, saith the Lord God.", "wycliffe": "And thei schulen coumforte you, whanne ye schulen se the weie of hem and the fyndyngis of hem; and ye schulen knowe, that not in veyn Y dide alle thingis, what euer thingis Y dide there ynne, seith the Lord almyyti.", "rotherham": "Yea they shall console you, when ye see their way and their doings,— So shall ye know that not without cause, have I done, anything that I have done with her, Declareth My Lord Yahweh.", "darby": "And they shall comfort you, when ye see their way and their doings; and ye shall know that I have not done without cause all that I have done in it, saith the Lord Jehovah.", "twenty": "", "jps": "and they shall comfort you, when ye see their way and their doings, and ye shall know that I have not done without cause all that I have done in it, saith the L-rd GOD.'", "acv": "And they shall comfort you when ye see their way and their doings. And ye shall know that I have not done all that I have done in it without cause, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "They shall comfort you, when ye see their ways and their doings; and ye shall know that not without cause I have done all that I have done to her, saith the Lord Jehovah.", "webster": "And they shall comfort you, when ye see their ways and their doings: and ye shall know that I have not done without cause all that I have done in it, saith the Lord GOD.", "vulgate": "et consolabuntur vos cum videritis viam eorum et adinventiones eorum et cognoscetis quod non frustra fecerim omnia quae feci in ea ait Dominus Deus;", "brenton": "And they shall comfort you, because ye shall see their ways and their thoughts: and ye shall know that I have not done in vain all that I have done in it, saith the Lord."}}]}, {"c": 15, "verses": [{"v": 1, "ref": "15:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And thee word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "15:2", "o": "בֶּן אָדָ֕ם מַה יִּֽהְיֶ֥ה עֵץ הַ/גֶּ֖פֶן מִ/כָּל עֵ֑ץ הַ/זְּמוֹרָ֕ה אֲשֶׁ֥ר הָיָ֖ה בַּ/עֲצֵ֥י הַ/יָּֽעַר", "en": {"kjv": "Son of man, What is the vine tree more than any tree, or than a branch which is among the trees of the forest?", "web": "Son of man, what is the vine tree more than any tree, the vine-branch which is among the trees of the forest?", "bsb": "“Son of man, how does the wood of the vine surpass any other branch among the trees in the forest?", "asv": "Son of man, what is the vine-tree more than any tree, the vine-branch which is among the trees of the forest?", "ylt": "`Son of man, What is the vine-tree more than any tree? The vine-branch that hath been, Among trees of the forest?", "dra": "Son of man, what shall be made of the wood of the vine, out of all the trees of the woods that are among the trees of the forests?", "bbe": "Son of man, what is the vine-tree more than any branching tree which is among the trees of the woods?", "geneva": "Sonne of man, what commeth of the vine tree aboue all other trees? and of the vine braunch, which is among the trees of ye forest?", "wycliffe": "and he seide, Sone of man, what schal be don to the tre of a vyne, of alle the trees of woodis, that ben among the trees of woodis?", "rotherham": "Son of man, What can the vine-tree be more than any other tree,—any branch which hath been found among the trees of the forest?", "darby": "Son of man, what is the wood of the vine more than any wood, the vine-branch, which is among the trees of the forest?", "twenty": "", "jps": "'Son of man, what is the vine-tree more than any tree, the vine branch which grew up among the trees of the forest?", "acv": "Son of man, what is the vine tree more than any tree, the vine branch which is among the trees of the forest?", "anderson": "", "haweis": "", "noyes": "Son of man, what is the wood of the vine more than any wood,—a branch, that is among the trees of the forest?", "webster": "Son of man, What is the vine-tree more than any tree, [or than] a branch which is among the trees of the forest?", "vulgate": "fili hominis quid fiet ligno vitis ex omnibus lignis nemorum quae sunt inter ligna silvarum;", "brenton": "And thou, son of man—of all the wood, of the branches that are among the trees of the forest, what shall be made of the wood of the vine?"}}, {"v": 3, "ref": "15:3", "o": "הֲ/יֻקַּ֤ח מִמֶּ֨/נּוּ֙ עֵ֔ץ לַ/עֲשׂ֖וֹת לִ/מְלָאכָ֑ה אִם יִקְח֤וּ מִמֶּ֨/נּוּ֙ יָתֵ֔ד לִ/תְל֥וֹת עָלָ֖י/ו כָּל כֶּֽלִי", "en": {"kjv": "Shall wood be taken thereof to do any work? or will men take a pin of it to hang any vessel thereon?", "web": "Will wood be taken of it to make anything? Will men take a pin of it to hang any vessel on it?", "bsb": "Can wood be taken from it to make something useful? Or can one make from it a peg on which to hang utensils?", "asv": "Shall wood be taken thereof to make any work? or will men take a pin of it to hang any vessel thereon?", "ylt": "Is wood taken from it to use for work? Do they take of it a pin to hang any vessel on it?", "dra": "Shall wood be taken of it, to do any work, or shall a pin be made of it for any vessel to hang thereon?", "bbe": "Will its wood be used for any work? do men make of it a pin for hanging any vessel on?", "geneva": "Shall wood bee taken thereof to doe any worke? or wil men take a pin of it to hang any vessel thereon?", "wycliffe": "Whether tymbre schal be takun therof, that werk be maad? ether shal a stake be maad therof, that ony vessel hange ther onne?", "rotherham": "Shall there be taken from it wood, to be made into any work? Or will men take therefrom a peg, to hang thereon any vessel?", "darby": "Shall wood be taken thereof to do any work? or will [men] take a pin of it to hang any vessel thereon?", "twenty": "", "jps": "Shall wood be taken thereof to make any work? or will men take a pin of it to hang any vessel thereon?", "acv": "Shall wood be taken of it to make any work? Or will men take a pin of it to hang any vessel thereon?", "anderson": "", "haweis": "", "noyes": "Shall wood be taken from it to be wrought into any work? Or will men take a pin of it to hang a vessel upon?", "webster": "Shall wood be taken of it to do any work? or will [men] take a pin of it to hang any vessel upon it?", "vulgate": "numquid tolletur de ea lignum ut fiat opus aut fabricabitur de ea paxillus ut dependeat in eo quodcumque vas;", "brenton": "Will they take wood of it to make it fit for work? will they take of it a peg to hang any vessel upon it?"}}, {"v": 4, "ref": "15:4", "o": "הִנֵּ֥ה לָ/אֵ֖שׁ נִתַּ֣ן לְ/אָכְלָ֑ה אֵת֩ שְׁנֵ֨י קְצוֹתָ֜י/ו אָכְלָ֤ה הָ/אֵשׁ֙ וְ/תוֹכ֣/וֹ נָחָ֔ר הֲ/יִצְלַ֖ח לִ/מְלָאכָֽה", "en": {"kjv": "Behold, it is cast into the fire for fuel; the fire devoureth both the ends of it, and the midst of it is burned. Is it meet for any work?", "web": "Behold, it is cast into the fire for fuel; the fire has devoured both its ends, and its midst is burned: is it profitable for any work?", "bsb": "No, it is cast into the fire for fuel. The fire devours both ends, and the middle is charred. Can it be useful for anything?", "asv": "Behold, it is cast into the fire for fuel; the fire hath devoured both the ends of it, and the midst of it is burned: is it profitable for any work?", "ylt": "Lo, to the fire it hath been given for fuel, Its two ends hath the fire eaten, And its midst hath been scorched! Is it profitable for work?", "dra": "Behold it is cast into the fire for fuel: the fire hath consumed both ends thereof, and the midst thereof is reduced to ashes: shall it be useful for any work?", "bbe": "See, it is put into the fire for burning: the fire has made a meal of its two ends and the middle part of it is burned; is it good for any work?", "geneva": "Behold, it is cast in the fire to be consumed: the fire consumeth both the endes of it, and the middes of it is burnt. Is it meete for any worke?", "wycliffe": "Lo! it is youun in to mete; fier wastide euer eithir part therof, and the myddis therof is dryuun in to deed sparcle; whether it schal be profitable to werk?", "rotherham": "Lo! into the fire, it is given up for fuel,— The two ends thereof, doth the fire devour, And the middle thereof is charred, Is it fit for any work?", "darby": "Behold, it is given to the fire for fuel: the fire consumeth both the ends of it, and the midst of it is burned; is it fit for [any] work?", "twenty": "", "jps": "Behold, it is cast into the fire for fuel; the fire hath devoured both the ends of it, and the midst of it is singed; is it profitable for any work?", "acv": "Behold, it is cast into the fire for fuel. The fire has devoured both the ends of it, and the midst of it is burned. Is it profitable for any work?", "anderson": "", "haweis": "", "noyes": "Behold, it is cast into the fire for fuel; the fire devoureth both the ends of it, and the middle of it is burned. Is it then fit for any work?", "webster": "Behold, it is cast into the fire for fuel; the fire devoureth both the ends of it, and the midst of it is burned. Is it suitable for [any] work?", "vulgate": "ecce igni datum est in escam utramque partem eius consumpsit ignis et medietas eius redacta est in favillam numquid utile erit ad opus;", "brenton": "It is only given to the fire to be consumed; the fire consumes that which is yearly pruned of it, and it is utterly gone. Will it be useful for any work?"}}, {"v": 5, "ref": "15:5", "o": "הִנֵּה֙ בִּֽ/הְיוֹת֣/וֹ תָמִ֔ים לֹ֥א יֵֽעָשֶׂ֖ה לִ/מְלָאכָ֑ה אַ֣ף כִּי אֵ֤שׁ אֲכָלַ֨תְ/הוּ֙ וַ/יֵּחָ֔ר וְ/נַעֲשָׂ֥ה ע֖וֹד לִ/מְלָאכָֽה", "en": {"kjv": "Behold, when it was whole, it was meet for no work: how much less shall it be meet yet for any work, when the fire hath devoured it, and it is burned?", "web": "Behold, when it was whole, it was meet for no work: how much less, when the fire has devoured it, and it is burned, shall it yet be meet for any work!", "bsb": "Even when it was whole, it could not be made useful. How much less can it ever be useful when the fire has consumed it and charred it!", "asv": "Behold, when it was whole, it was meet for no work: how much less, when the fire hath devoured it, and it is burned, shall it yet be meet for any work!", "ylt": "Lo, in its being perfect it is not used for work, How much less, when fire hath eaten of it, And it is scorched, Hath it been used yet for work?", "dra": "Even when it was whole it was not fit for work: how much less, when the fire hath devoured and consumed it, shall any work be made of it?", "bbe": "Truly, before it was cut down, it was not used for any purpose: how much less, when the fire has made a meal of it and it is burned, will it be made into anything?", "geneva": "Behold, when it was whole, it was meete for no worke: how much lesse shall it bee meete for any worke, when the fire hath consumed it, and it is burnt?", "wycliffe": "Yhe, whanne it was hool, it was not couenable to werk; hou myche more whanne fier hath deuourid, and hath brent it, no thing of werk schal be maad therof?", "rotherham": "Lo! while it was yet whole, it could not be made into any work,— how much less when !the fire hath devoured it. and it is charred, can it still be made into any work?", "darby": "Behold, when it was whole, it was used for no work; how much less when the fire hath consumed it, and it is burned, should it yet be used for any work?", "twenty": "", "jps": "Behold, when it was whole, it was meet for no work; how much less, when the fire hath devoured it, and it is singed, shall it yet be meet for any work?", "acv": "Behold, when it was whole, it was fit for no work. How much less, when the fire has devoured it, and it is burned, shall it yet be fit for any work!", "anderson": "", "haweis": "", "noyes": "Behold, when it was whole, nothing could be made of it; how much less can anything be made of it when the fire hath devoured it and it is burned!", "webster": "Behold, when it was whole, it was fit for no work: how much less then shall it be fit for [any] work, when the fire hath devoured it, and it is burned?", "vulgate": "etiam cum esset integrum non erat aptum ad opus quanto magis cum ignis illud devoraverit et conbuserit nihil ex eo fiet operis;", "brenton": "Not even while it is yet whole will it be useful for any work: if the fire shall have utterly consumed it, will it still be fit for work?"}}, {"v": 6, "ref": "15:6", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה כַּ/אֲשֶׁ֤ר עֵץ הַ/גֶּ֨פֶן֙ בְּ/עֵ֣ץ הַ/יַּ֔עַר אֲשֶׁר נְתַתִּ֥י/ו לָ/אֵ֖שׁ לְ/אָכְלָ֑ה כֵּ֣ן נָתַ֔תִּי אֶת יֹשְׁבֵ֖י יְרוּשָׁלִָֽם", "en": {"kjv": "Therefore thus saith the Lord God; As the vine tree among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.", "web": "Therefore thus says the Lord Yahweh: As the vine tree among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.", "bsb": "Therefore this is what the Lord GOD says: ‘Like the wood of the vine among the trees of the forest, which I have given to the fire for fuel, so I will give up the people of Jerusalem.", "asv": "Therefore thus saith the Lord Jehovah: As the vine-tree among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.", "ylt": "Therefore, thus said the Lord Jehovah: As the vine-tree among trees of the forest, That I have given to the fire for fuel, So I have given the inhabitants of Jerusalem.", "dra": "Therefore thus saith the Lord God: As the vine tree among the trees of the forests which I have given to the fire to be consumed, so will I deliver up the inhabitants of Jerusalem.", "bbe": "For this cause the Lord has said: Like the vine-tree among the trees of the woods which I have given to the fire for burning, so will I give the people of Jerusalem.", "geneva": "Therefore thus sayth the Lord God, As the vine tree, that is among the trees of the forest, which I haue giuen to the fire to be consumed, so will I giue the inhabitants of Ierusalem.", "wycliffe": "Therfor the Lord God seith thes thingis, As the tre of a vyne is among the trees of woodis, which Y yaf to fier to deuoure, so Y yaf the dwelleris of Jerusalem,", "rotherham": "Therefore, Thus, saith My Lord Yahweh, As a vine-tree among the trees of the forest, which I have given up to the fire for fuel, so have I given up the inhabitants of Jerusalem.", "darby": "Therefore thus saith the Lord Jehovah: As the wood of the vine among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: As the vine-tree among the trees of the forest, which I have given to the fire for fuel, so do I give the inhabitants of Jerusalem.", "acv": "Therefore thus says the lord Jehovah: As the vine tree among the trees of the forest, which I have given to the fire for fuel, so I will give the inhabitants of Jerusalem.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: As the wood of the vine among the trees of the forest, which I have given to the fire for fuel, so will I give to it the inhabitants of Jerusalem.", "webster": "Therefore thus saith the Lord GOD; As the vine-tree among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.", "vulgate": "propterea haec dicit Dominus Deus quomodo lignum vitis inter ligna silvarum quod dedi igni ad devorandum sic tradidi habitatores Hierusalem;", "brenton": "Therefore say, Thus saith the Lord, As the vine-tree among the trees of the forest, which I have given up to the fire to be consumed, so have I given up the inhabitants of Jerusalem."}}, {"v": 7, "ref": "15:7", "o": "וְ/נָתַתִּ֤י אֶת פָּנַ/י֙ בָּ/הֶ֔ם מֵ/הָ/אֵ֣שׁ יָצָ֔אוּ וְ/הָ/אֵ֖שׁ תֹּֽאכְלֵ֑/ם וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה בְּ/שׂוּמִ֥/י אֶת פָּנַ֖/י בָּ/הֶֽם", "en": {"kjv": "And I will set my face against them; they shall go out from one fire, and another fire shall devour them; and ye shall know that I am the Lord, when I set my face against them.", "web": "I will set my face against them; they shall go out from the fire, but the fire shall devour them; and you shall know that I am Yahweh, when I set my face against them.", "bsb": "And I will set My face against them. Though they may have escaped the fire, yet another fire will consume them. And when I set My face against them, you will know that I am the LORD.", "asv": "And I will set my face against them; they shall go forth from the fire, but the fire shall devour them; and ye shall know that I am Jehovah, when I set my face against them.", "ylt": "And I have set My face against them, From the fire they have gone forth, And the fire doth consume them, And ye have known that I am Jehovah, In My setting My face against them.", "dra": "And I will set my face against them: they shall go out from fire, and fire shall consume them: and you shall know that I am the Lord, when I shall have set my face against them.", "bbe": "And my face will be turned against them; and though they have come out of the fire they will be burned up by it; and it will be clear to you that I am the Lord when my face is turned against them.", "geneva": "And I will set my face against them: they shall go out from one fire, and another fire shall consume them: and ye shall know, that I am the Lord, when I set my face against them,", "wycliffe": "and Y schal sette my face ayens hem. Thei schulen go out of the fier, and fier schal waaste hem; and ye schulen wite, that Y am the Lord, whanne Y schal sette my face ayens hem,", "rotherham": "Therefore will I set my face against them, Out of one fire, have they come forth But another fire, shall devour them,—So shall ye know that, I, am Yahweh, by my setting my face against them;", "darby": "And I will set my face against them: they shall go forth from [one] fire, and [another] fire shall devour them; and ye shall know that I [am] Jehovah when I set my face against them.", "twenty": "", "jps": "And I will set My face against them; out of the fire are they come forth, and the fire shall devour them; and ye shall know that I am HaShem, when I set My face against them.", "acv": "And I will set my face against them. They shall go forth from the fire, but the fire shall devour them. And ye shall know that I am Jehovah when I set my face against them.", "anderson": "", "haweis": "", "noyes": "And I will set my face against them; they shall go out from one fire, and another fire shall devour them; and ye shall know that I am Jehovah, when I set my face against them.", "webster": "And I will set my face against them; they shall go out from [one] fire, and [another] fire shall devour them; and ye shall know that I [am] the LORD, when I set my face against them.", "vulgate": "et ponam faciem meam in eos de igne egredientur et ignis consumet eos et scietis quia ego Dominus cum posuero faciem meam in eos;", "brenton": "And I will set my face against them; they shall go forth of the fire, and yet fire shall devour them; and they shall know that I am the Lord, when I have set my face against them."}}, {"v": 8, "ref": "15:8", "o": "וְ/נָתַתִּ֥י אֶת הָ/אָ֖רֶץ שְׁמָמָ֑ה יַ֚עַן מָ֣עֲלוּ מַ֔עַל נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And I will make the land desolate, because they have committed a trespass, saith the Lord God.", "web": "I will make the land desolate, because they have committed a trespass, says the Lord Yahweh.", "bsb": "Thus I will make the land desolate, because they have acted unfaithfully,’ declares the Lord GOD.”", "asv": "And I will make the land desolate, because they have committed a trespass, saith the Lord Jehovah.", "ylt": "And I have made the land a desolation, Because they have committed a trespass, An affirmation of the Lord Jehovah!'", "dra": "And I shall have made their land a wilderness, and desolate, because they have been transgressors, saith the Lord God.", "bbe": "And I will make the land a waste because they have done evil, says the Lord.", "geneva": "And when I make the lande waste, because they haue greatly offended, saith the Lord God.", "wycliffe": "and schal yyue the lond with out weie and desolat, for thei weren trespassours, seith the Lord God.", "rotherham": "I will therefore give up the land as a desolation, —because they have committed treachery, Declareth My Lord., Yahweh.", "darby": "And I will make the land a desolation, because they have wrought unfaithfulness, saith the Lord Jehovah.", "twenty": "", "jps": "And I will make the land desolate, because they have acted treacherously, saith the L-rd GOD.'", "acv": "And I will make the land desolate because they have committed a trespass, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will make the land desolate, because they have grievously trespassed, saith the Lord Jehovah.", "webster": "And I will make the land desolate, because they have committed a trespass, saith the Lord GOD.", "vulgate": "et dedero terram inviam et desolatam eo quod praevaricatores extiterint dicit Dominus Deus;", "brenton": "And I will give up the land to ruin, because they have utterly transgressed, saith the Lord."}}]}, {"c": 16, "verses": [{"v": 1, "ref": "16:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Again the word of the Lord came unto me, saying,", "web": "Again Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "Again the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Again, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Again the word of HaShem came unto me, saying:", "acv": "Again the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "Moreover the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "16:2", "o": "בֶּן אָדָ֕ם הוֹדַ֥ע אֶת יְרוּשָׁלִַ֖ם אֶת תּוֹעֲבֹתֶֽי/הָ", "en": {"kjv": "Son of man, cause Jerusalem to know her abominations,", "web": "Son of man, cause Jerusalem to know her abominations;", "bsb": "“Son of man, confront Jerusalem with her abominations", "asv": "Son of man, cause Jerusalem to know her abominations;", "ylt": "`Son of man, cause Jerusalem to know her abominations, and thou hast said:", "dra": "Son of man, make known to Jerusalem her abominations.", "bbe": "Son of man, make clear to Jerusalem her disgusting ways,", "geneva": "Sonne of man, cause Ierusalem to knowe her abominations,", "wycliffe": "and he seide, Sone of man, make thou knowun to Jerusalem her abhomynaciouns; and thou schalt seie,", "rotherham": "Son of man Let Jerusalem know her abominations,", "darby": "Son of man, cause Jerusalem to know her abominations,", "twenty": "", "jps": "'Son of man, cause Jerusalem to know her abominations,", "acv": "Son of man, cause Jerusalem to know her abominations,", "anderson": "", "haweis": "", "noyes": "Son of man, cause Jerusalem to know her abominations,", "webster": "Son of man, cause Jerusalem to know her abominations,", "vulgate": "fili hominis notas fac Hierusalem abominationes suas;", "brenton": "Son of man, testify to Jerusalem of her iniquities;"}}, {"v": 3, "ref": "16:3", "o": "וְ/אָמַרְתָּ֞ כֹּה אָמַ֨ר אֲדֹנָ֤/י יְהוִה֙ לִ/יר֣וּשָׁלִַ֔ם מְכֹרֹתַ֨יִ/ךְ֙ וּ/מֹ֣לְדֹתַ֔יִ/ךְ מֵ/אֶ֖רֶץ הַֽ/כְּנַעֲנִ֑י אָבִ֥י/ךְ הָ/אֱמֹרִ֖י וְ/אִמֵּ֥/ךְ חִתִּֽית", "en": {"kjv": "And say, Thus saith the Lord God unto Jerusalem; Thy birth and thy nativity is of the land of Canaan; thy father was an Amorite, and thy mother an Hittite.", "web": "and say, Thus says the Lord Yahweh to Jerusalem: Your birth and your birth is of the land of the Canaanite; the Amorite was your father, and your mother was a Hittite.", "bsb": "and tell her that this is what the Lord GOD says to Jerusalem: Your origin and your birth were in the land of the Canaanites. Your father was an Amorite and your mother a Hittite.", "asv": "and say, Thus saith the Lord Jehovah unto Jerusalem: Thy birth and thy nativity is of the land of the Canaanite; the Amorite was thy father, and thy mother was a Hittite.", "ylt": "Thus said the Lord Jehovah to Jerusalem: Thy birth and thy nativity Are of the land of the Canaanite, Thy father the Amorite, and thy mother a Hittite.", "dra": "And thou shalt say: Thus saith the Lord God to Jerusalem: Thy root, and thy nativity is of the land of Chanaan, thy father was an Amorrhite, and thy mother a Cethite.", "bbe": "And say, This is what the Lord has said to Jerusalem: Your start and your birth was from the land of the Canaanite; an Amorite was your father and your mother was a Hittite.", "geneva": "And say, Thus saith the Lord God vnto Ierusalem, Thine habitation and thy kindred is of the land of Canaan: thy father was an Amorite, and thy mother an Hittite.", "wycliffe": "The Lord God seith these thingis. A! thou Jerusalem, thi rote and thi generacioun is of the lond of Canaan; thi fadir is Amorrei, and thi moder is Cetei.", "rotherham": "Therefore shalt thou say— Thus saith My Lord. Yahweh To Jerusalem, Thine origin and thy birth, were of the land of the Canaanite,— Thy father was the Amorite And thy mother a Hittite", "darby": "and say, Thus saith the Lord Jehovah unto Jerusalem: Thy birth and thy nativity is of the land of the Canaanite: thy father was an Amorite, and thy mother a Hittite.", "twenty": "", "jps": "and say: Thus saith the L-rd GOD unto Jerusalem: Thine origin and thy nativity is of the land of the Canaanite; the Amorite was thy father, and thy mother was a Hittite.", "acv": "and say, Thus says the lord Jehovah to Jerusalem: Thy birth and thy nativity is from the land of the Canaanite. The Amorite was thy father, and thy mother was a Hittite.", "anderson": "", "haweis": "", "noyes": "and say, Thus saith the Lord Jehovah to Jerusalem: Thine origin and thy nativity were of the land of Canaan. Thy father was an Amorite, and thy mother a Hittite.", "webster": "And say, Thus saith the Lord GOD to Jerusalem; Thy birth and thy nativity [is] of the land of Canaan; thy father [was] an Amorite, and thy mother a Hittite.", "vulgate": "et dices haec dicit Dominus Deus Hierusalem radix tua et generatio tua de terra chananea pater tuus Amorreus et mater tua Cetthea;", "brenton": "and thou shalt say, Thus saith the Lord to Jerusalem; Thy root and thy birth are of the land of Chanaan: thy father was an Amorite, and thy mother a Chettite."}}, {"v": 4, "ref": "16:4", "o": "וּ/מוֹלְדוֹתַ֗יִ/ךְ בְּ/י֨וֹם הוּלֶּ֤דֶת אֹתָ/ךְ֙ לֹֽא כָרַּ֣ת שָׁרֵּ֔/ךְ וּ/בְ/מַ֥יִם לֹֽא רֻחַ֖צְתְּ לְ/מִשְׁעִ֑י וְ/הָמְלֵ֨חַ֙ לֹ֣א הֻמְלַ֔חַתְּ וְ/הָחְתֵּ֖ל לֹ֥א חֻתָּֽלְתְּ", "en": {"kjv": "And as for thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water to supple thee; thou wast not salted at all, nor swaddled at all.", "web": "As for your birth, in the day you were born your navel was not cut, neither were you washed in water to cleanse you; you weren’t salted at all, nor swaddled at all.", "bsb": "On the day of your birth your cord was not cut, nor were you washed with water for cleansing. You were not rubbed with salt or wrapped in cloths.", "asv": "And as for thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water to cleanse thee; thou wast not salted at all, nor swaddled at all.", "ylt": "As to thy nativity, in the day thou wast born, Thou--thy navel hath not been cut, And in water thou wast not washed for ease, And thou hast not been salted at all, And thou hast not been swaddled at all.", "dra": "And when thou wast born, in the day of thy nativity thy navel was not cut, neither wast thou washed with water for thy health, nor salted with salt, nor swaddled with clouts.", "bbe": "As for your birth, on the day of your birth your cord was not cut and you were not washed in water to make you clean; you were not salted or folded in linen bands.", "geneva": "And in thy natiuitie whe thou wast borne, thy nauell was not cut: thou wast not washed in water to soften thee: thou wast not salted with salt, nor swadled in cloutes.", "wycliffe": "And whanne thou were borun, thi nawle was not kit awei in the dai of thi birthe, and thou were not waischun in watir in to helthe, nethir saltid with salt, nether wlappid in clothis.", "rotherham": "And, as for thy birth, in the day thou wast born, Thy navel-cord was not cut, And, in water, wast thou not bathed to cleanse thee,— And, as for being salted, thou was not salted, And, as for being bandaged, thou wast not bandaged.", "darby": "And as for thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water for cleansing; thou wast not rubbed with salt at all, nor swaddled at all.", "twenty": "", "jps": "And as for thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water for cleansing; thou was not salted at all, nor swaddled at all.", "acv": "And as for thy nativity, in the day thou were born thy navel was not cut, nor were thou washed in water to cleanse thee. Thou were not salted at all, nor swaddled at all.", "anderson": "", "haweis": "", "noyes": "And as to thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water so as to be cleansed. Thou wast not sprinkled with salt, nor wrapped in swaddling-clothes.", "webster": "And [as for] thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water to supple [thee]; thou wast not salted at all, nor swaddled at all.", "vulgate": "et quando nata es in die ortus tui non est praecisus umbilicus tuus et in aqua non es lota in salutem nec sale salita nec involuta pannis;", "brenton": "And as for thy birth in the day wherein thou wast born, thou didst not bind thy breasts, and thou wast not washed in water, neither wast thou salted with salt, neither wast thou swathed in swaddling-bands."}}, {"v": 5, "ref": "16:5", "o": "לֹא חָ֨סָה עָלַ֜יִ/ךְ עַ֗יִן לַ/עֲשׂ֥וֹת לָ֛/ךְ אַחַ֥ת מֵ/אֵ֖לֶּה לְ/חֻמְלָ֣ה עָלָ֑יִ/ךְ וַֽ/תֻּשְׁלְכִ֞י אֶל פְּנֵ֤י הַ/שָּׂדֶה֙ בְּ/גֹ֣עַל נַפְשֵׁ֔/ךְ בְּ/י֖וֹם הֻלֶּ֥דֶת אֹתָֽ/ךְ", "en": {"kjv": "None eye pitied thee, to do any of these unto thee, to have compassion upon thee; but thou wast cast out in the open field, to the lothing of thy person, in the day that thou wast born.", "web": "No eye pitied you, to do any of these things to you, to have compassion on you; but you were cast out in the open field, for that your person was abhorred, in the day that you were born.", "bsb": "No one cared enough for you to do even one of these things out of compassion for you. Instead, you were thrown out into the open field, because you were despised on the day of your birth.", "asv": "No eye pitied thee, to do any of these things unto thee, to have compassion upon thee; but thou wast cast out in the open field, for that thy person was abhorred, in the day that thou wast born.", "ylt": "No eye hath had pity on thee, to do to thee any of these, To have compassion on thee, And thou art cast on the face of the field, With loathing of thy person. In the day thou hast been born--thou!", "dra": "No eye had pity on thee to do any of these things for thee, out of compassion to thee: but thou wast cast out upon the face of the earth in the abjection of thy soul, in the day that thou wast born.", "bbe": "No eye had pity on you to do any of these things to you or to be kind to you; but you were put out into the open country, because your life was hated at the time of your birth.", "geneva": "None eye pitied thee to do any of these vnto thee, for to haue compassion vpon thee, but thou wast cast out in the open fielde to the contempt of thy person in ye day that thou wast borne.", "wycliffe": "An iye sparide not on thee, that it hauynge merci on thee, dide to thee oon of these thingis; but thou were cast forth on the face of erthe, in the castynge out of thi soule, in the dai in which thou were borun.", "rotherham": "No eye, threw a shield over thee, by doing for thee one of these things taking pity on thee,- But thou wast cast out on the face of the field Because thy person, was abhorred, in the day thou wast born.", "darby": "No eye pitied thee, to do any of these unto thee, to have compassion upon thee; but thou wast cast out in the open field, from abhorrence of thy person, in the day that thou wast born.", "twenty": "", "jps": "No eye pitied thee, to do any of these unto thee, to have compassion upon thee; but thou wast cast out in the open field in the loathsomeness of thy person, in the day that thou wast born.", "acv": "No eye pitied thee, to do any of these things to thee, to have compassion upon thee, but thou were cast out in the open field. For thy person was abhorred, in the day that thou were born.", "anderson": "", "haweis": "", "noyes": "No eye pitied thee, to do to thee any of these things, to have compassion upon thee; but thou wast cast out into the open field, so as to loathe thyself, on the day thou wast born.", "webster": "No eye pitied thee, to do any of these to thee, to have compassion upon thee; but thou wast cast out in the open field, to the lothing of thy person, in the day that thou wast born.", "vulgate": "non pepercit super te oculus ut facerem tibi unum de his miseratus tui sed proiecta es super faciem terrae in abiectione animae tuae in die qua nata es;", "brenton": "Nor did mine eye pity thee, to do for thee one of all these things, to feel at all for thee; but thou wast cast out on the face of the field, because of the deformity of thy person, in the day wherein thou wast born."}}, {"v": 6, "ref": "16:6", "o": "וָ/אֶעֱבֹ֤ר עָלַ֨יִ/ךְ֙ וָֽ/אֶרְאֵ֔/ךְ מִתְבּוֹסֶ֖סֶת בְּ/דָמָ֑יִ/ךְ וָ/אֹ֤מַר לָ/ךְ֙ בְּ/דָמַ֣יִ/ךְ חֲיִ֔י וָ/אֹ֥מַר לָ֖/ךְ בְּ/דָמַ֥יִ/ךְ חֲיִֽי", "en": {"kjv": "And when I passed by thee, and saw thee polluted in thine own blood, I said unto thee when thou wast in thy blood, Live; yea, I said unto thee when thou wast in thy blood, Live.", "web": "When I passed by you, and saw you wallowing in your blood, I said to you, Though you are in your blood, live; yes, I said to you, Though you are in your blood, live.", "bsb": "Then I passed by and saw you wallowing in your blood, and as you lay there in your blood I said to you, ‘Live!’ There I said to you, ‘Live!’", "asv": "And when I passed by thee, and saw thee weltering in thy blood, I said unto thee, Though thou art in thy blood, live; yea, I said unto thee, Though thou art in thy blood, live.", "ylt": "And I do pass over by thee, And I see thee trodden down in thy blood, And I say to thee in thy blood, Live, And I say to thee in thy blood, Live.", "dra": "And passing by thee, I saw that thou wast trodden under foot in thy own blood: and I said to thee when thou wast in thy blood: Live: I have said to thee: Live in thy blood.", "bbe": "And when I went past you and saw you stretched out in your blood, I said to you, Though you are stretched out in your blood, have life;", "geneva": "And when I passed by thee, I saw thee polluted in thine owne blood, and I said vnto thee, whe thou wast in thy blood, Thou shalt liue: euen when thou wast in thy blood, I saide vnto thee, Thou shalt liue.", "wycliffe": "Forsothe Y passide bi thee, and Y siy thee defoulid in thi blood; and Y seide to thee, whanne thou were in thi blood, Lyue thou; sotheli Y seide to thee in thi blood, Lyue thou.", "rotherham": "And I passed by thee, and looked upon thee, thrusting about thee in thy blood, And said to thee— Despite thy blood, live! Yea I said to thee— Despite thy blood, live!", "darby": "And I passed by thee, and saw thee weltering in thy blood, and I said unto thee, in thy blood, Live! yea, I said unto thee, in thy blood, Live!", "twenty": "", "jps": "And when I passed by thee, and saw thee wallowing in thy blood, I said unto thee: In thy blood, live; yea, I said unto thee: In thy blood, live;", "acv": "And when I passed by thee, and saw thee weltering in thy blood, I said to thee, in thy blood, Live! Yea, I said to thee, in thy blood, Live!", "anderson": "", "haweis": "", "noyes": "And when I passed by thee, and saw thee in danger of being trodden under foot in thy blood, I said to thee when thou wast in thy blood, Live! yea, I said to thee when thou wast in thy blood, Live!", "webster": "And when I passed by thee, and saw thee polluted in thy own blood, I said to thee [when thou wast] in thy blood, Live; yes, I said to thee [when thou wast] in thy blood, Live.", "vulgate": "transiens autem per te vidi te conculcari in sanguine tuo et dixi tibi cum esses in sanguine tuo vive dixi inquam tibi in sanguine tuo vive;", "brenton": "And I passed by to thee, and saw thee polluted in thy blood; and I said to thee, Let there be life out of thy blood:"}}, {"v": 7, "ref": "16:7", "o": "רְבָבָ֗ה כְּ/צֶ֤מַח הַ/שָּׂדֶה֙ נְתַתִּ֔י/ךְ וַ/תִּרְבִּי֙ וַֽ/תִּגְדְּלִ֔י וַ/תָּבֹ֖אִי בַּ/עֲדִ֣י עֲדָיִ֑ים שָׁדַ֤יִם נָכֹ֨נוּ֙ וּ/שְׂעָרֵ֣/ךְ צִמֵּ֔חַ וְ/אַ֖תְּ עֵרֹ֥ם וְ/עֶרְיָֽה", "en": {"kjv": "I have caused thee to multiply as the bud of the field, and thou hast increased and waxen great, and thou art come to excellent ornaments: thy breasts are fashioned, and thine hair is grown, whereas thou wast naked and bare.", "web": "I caused you to multiply as that which grows in the field, and you increased and grew great, and you attained to excellent ornament; your breasts were fashioned, and your hair was grown; yet you were naked and bare.", "bsb": "I made you thrive like a plant of the field. You grew up and matured and became very beautiful. Your breasts were formed and your hair grew, but you were naked and bare.", "asv": "I caused thee to multiply as that which groweth in the field, and thou didst increase and wax great, and thou attainedst to excellent ornament; thy breasts were fashioned, and thy hair was grown; yet thou wast naked and bare.", "ylt": "A myriad--as the shoot of the field I have made thee, And thou art multiplied, and art great, And comest in with an excellent adornment, Breasts have been formed, and thy hair hath grown--And thou, naked and bare!", "dra": "I caused thee to multiply as the bud of the field: and thou didst increase and grow great, and advancedst, and camest to woman's ornament: thy breasts were fashioned, and thy hair grew: and thou was naked, and full of confusion.", "bbe": "And be increased in number like the buds of the field; and you were increased and became great, and you came to the time of love: your breasts were formed and your hair was long; but you were uncovered and without clothing.", "geneva": "I haue caused thee to multiplie as the bud of the fielde, and thou hast increased and waxen great, and thou hast gotten excellent ornaments: thy breastes are facioned, thine heare is growen, where as thou wast naked and bare.", "wycliffe": "Y yaf thee multiplied as the seed of a feeld, and thou were multiplied, and maad greet; and thou entridist, and camest fulli to wymmens ournyng; thi tetis wexiden greet, and thin heer wexide; and thou were nakid, and ful of schenschipe.", "rotherham": "Into myriads—like the bud of the field, made I thee, And thou didst increase and become well grown, and didst attain to most excellent adornments,— Thy breasts were well-formed And thy hair was grown, But thou thyself wast utterly naked.", "darby": "I caused thee to multiply, as the bud of the field; and thou didst increase and grow great, and thou camest to fulness of beauty; [thy] breasts were fashioned, and thy hair grew: but thou wast naked and bare.", "twenty": "", "jps": "I cause thee to increase, even as the growth of the field. And thou didst increase and grow up, and thou camest to excellent beauty: thy breasts were fashioned, and thy hair was grown; yet thou wast naked and bare.", "acv": "I caused thee to multiply as that which grows in the field, and thou increased and grew great. And thou attained to excellent ornament, thy breasts were fashioned, and thy hair was grown. Yet thou were naked and bare.", "anderson": "", "haweis": "", "noyes": "I caused thee to increase like the plant of the field, and thou didst grow, and become tall, and didst attain to distinguished charms. Thy breasts swelled, and thy hair grew, whereas thou wast naked and bare.", "webster": "I have caused thee to multiply as the bud of the field, and thou hast increased and become great, and thou art come to excellent ornaments: [thy] breasts are fashioned, and thy hair is grown, whereas thou [wast] naked and bare.", "vulgate": "multiplicatam quasi germen agri dedi te et multiplicata es et grandis effecta et ingressa es et pervenisti ad mundum muliebrem ubera tua intumuerunt et pilus tuus germinavit et eras nuda et confusionis plena;", "brenton": "increase; I have made thee as the springing grass of the field. So thou didst increase and grow, and didst enter into great cities: thy breasts were set, and thy hair grew, whereas thou wast naked and bare."}}, {"v": 8, "ref": "16:8", "o": "וָ/אֶעֱבֹ֨ר עָלַ֜יִ/ךְ וָ/אֶרְאֵ֗/ךְ וְ/הִנֵּ֤ה עִתֵּ/ךְ֙ עֵ֣ת דֹּדִ֔ים וָ/אֶפְרֹ֤שׂ כְּנָפִ/י֙ עָלַ֔יִ/ךְ וָ/אֲכַסֶּ֖ה עֶרְוָתֵ֑/ךְ וָ/אֶשָּׁ֣בַֽע לָ֠/ךְ וָ/אָב֨וֹא בִ/בְרִ֜ית אֹתָ֗/ךְ נְאֻ֛ם אֲדֹנָ֥/י יְהוִ֖ה וַ/תִּ֥הְיִי לִֽ/י", "en": {"kjv": "Now when I passed by thee, and looked upon thee, behold, thy time was the time of love; and I spread my skirt over thee, and covered thy nakedness: yea, I sware unto thee, and entered into a covenant with thee, saith the Lord God, and thou becamest mine.", "web": "Now when I passed by you, and looked at you, behold, your time was the time of love; and I spread my skirt over you, and covered your nakedness: yes, I swore to you, and entered into a covenant with you, says the Lord Yahweh, and you became mine.", "bsb": "Then I passed by and saw you, and you were indeed old enough for love. So I spread My cloak over you and covered your nakedness. I pledged Myself to you, entered into a covenant with you, and you became Mine, declares the Lord GOD.", "asv": "Now when I passed by thee, and looked upon thee, behold, thy time was the time of love; and I spread my skirt over thee, and covered thy nakedness: yea, I sware unto thee, and entered into a covenant with thee, saith the Lord Jehovah, and thou becamest mine.", "ylt": "And I pass over by thee, and I see thee, And lo, thy time is a time of loves, And I spread My skirt over thee, And I cover thy nakedness, And I swear to thee, and come in to a covenant with thee, An affirmation of the Lord Jehovah, And thou dost become Mine.", "dra": "And I passed by thee, and saw thee: and behold thy time was the time of lovers: and I spread my garment over thee, and covered thy ignominy. and I swore to thee, and I entered into a covenant with thee, saith the Lord God: and thou becamest mine.", "bbe": "Now when I went past you, looking at you, I saw that your time was the time of love; and I put my skirts over you, covering your unclothed body: and I gave you my oath and made an agreement with you, says the Lord, and you became mine.", "geneva": "Nowe when I passed by thee, and looked vpon thee, beholde, thy time was as the time of loue, and I spred my skirtes ouer thee, and couered thy filthines: yea, I sware vnto thee, and entred into a couenant with thee, saith the Lord God, and thou becamest mine.", "wycliffe": "And Y passide bi thee, and Y siy thee, and lo! thi tyme, the tyme of louyeris; and Y spredde abrood my clothing on thee, and Y hilide thi schenschipe. And Y swoor to thee, and Y made a couenaunt with thee, seith the Lord God, and thou were maad a wijf to me.", "rotherham": "And I passed by thee and looked upon thee and lo! thy time was the time for endearments, So I spread my skirt over thee, and covered thy shame, And took an oath to thee And entered into covenant with thee. Declareth My Lord. Yahweh. And thou didst become mine.", "darby": "And I passed by thee, and looked upon thee, and behold, thy time was the time of love; and I spread my skirt over thee, and covered thy nakedness; and I swore unto thee, and entered into a covenant with thee, saith the Lord Jehovah, and thou becamest mine.", "twenty": "", "jps": "Now when I passed by thee, and looked upon thee, and, behold, thy time was the time of love, I spread my skirt over thee, and covered thy nakedness; yea, I swore unto thee, and entered into a covenant with thee, saith the L-rd GOD, and thou becamest Mine.", "acv": "Now when I passed by thee, and looked upon thee, behold, thy time was the time of love. And I spread my skirt over thee, and covered thy nakedness. Yea, I swore to thee, and entered into a covenant with thee, says the lord Jehovah, and thou became mine.", "anderson": "", "haweis": "", "noyes": "And when I passed by thee, and saw thee, behold, it was thy time, the time of love. And I spread my skirt over thee and covered thy nakedness; and I swore to thee, and entered into covenant with thee, and thou becamest mine.", "webster": "Now when I passed by thee, and looked upon thee, behold, thy time [was] the time of love; and I spread my skirt over thee, and covered thy nakedness: yes, I swore to thee, and entered into a covenant with thee, saith the Lord GOD, and thou becamest mine.", "vulgate": "et transivi per te et vidi te et ecce tempus tuum tempus amantium et expandi amictum meum super te et operui ignominiam tuam et iuravi tibi et ingressus sum pactum tecum ait Dominus Deus et facta es mihi;", "brenton": "And I passed by thee and saw thee, and, behold, it was thy time and a time of resting; and I spread my wings over thee, and covered thy shame, and swear to thee: and I entered into covenant with thee, saith the Lord, and thou becamest mine."}}, {"v": 9, "ref": "16:9", "o": "וָ/אֶרְחָצֵ֣/ךְ בַּ/מַּ֔יִם וָ/אֶשְׁטֹ֥ף דָּמַ֖יִ/ךְ מֵֽ/עָלָ֑יִ/ךְ וָ/אֲסֻכֵ֖/ךְ בַּ/שָּֽׁמֶן", "en": {"kjv": "Then washed I thee with water; yea, I throughly washed away thy blood from thee, and I anointed thee with oil.", "web": "Then washed I you with water; yes, I thoroughly washed away your blood from you, and I anointed you with oil.", "bsb": "Then I bathed you with water, rinsed off your blood, and anointed you with oil.", "asv": "Then washed I thee with water; yea, I thoroughly washed away thy blood from thee, and I anointed thee with oil.", "ylt": "And I do wash thee with water, And I wash away thy blood from off thee, And I anoint thee with perfume.", "dra": "And I washed thee with water, and cleansed away thy blood from thee: and I anointed thee with oil.", "bbe": "Then I had you washed with water, washing away all your blood and rubbing you with oil.", "geneva": "Then washed I thee with water: yea, I washed away thy blood from thee, and I anointed thee with oyle.", "wycliffe": "And Y waischide thee in water, and Y clenside awei thi blood fro thee, and Y anoyntide thee with oile.", "rotherham": "And I bathed thee in water, and rinsed thy blood from off thee, And anointed thee with oil;", "darby": "And I washed thee with water, and thoroughly washed away thy blood from thee, and I anointed thee with oil;", "twenty": "", "jps": "Then washed I thee with water; yea, I cleansed away thy blood from thee, and I anointed thee with oil.", "acv": "Then I washed thee with water. Yea, I thoroughly washed away thy blood from thee, and I anointed thee with oil.", "anderson": "", "haweis": "", "noyes": "Then I washed thee with water, yea, I thoroughly washed away thy blood from thee, and I anointed thee with oil.", "webster": "Then I washed thee with water; yes, I thoroughly washed away thy blood from thee, and I anointed thee with oil.", "vulgate": "et lavi te aqua et emundavi sanguinem tuum ex te et unxi te oleo;", "brenton": "And I washed thee in water, and washed thy blood from thee, and anointed thee with oil."}}, {"v": 10, "ref": "16:10", "o": "וָ/אַלְבִּישֵׁ֣/ךְ רִקְמָ֔ה וָ/אֶנְעֲלֵ֖/ךְ תָּ֑חַשׁ וָ/אֶחְבְּשֵׁ֣/ךְ בַּ/שֵּׁ֔שׁ וַ/אֲכַסֵּ֖/ךְ מֶֽשִׁי", "en": {"kjv": "I clothed thee also with broidered work, and shod thee with badgers’ skin, and I girded thee about with fine linen, and I covered thee with silk.", "web": "I clothed you also with embroidered work, and shod you with sealskin, and I dressed you about with fine linen, and covered you with silk.", "bsb": "I clothed you in embroidered cloth and gave you sandals of fine leather. I wrapped you in fine linen and covered you with silk.", "asv": "I clothed thee also with broidered work, and shod thee with sealskin, and I girded thee about with fine linen, and covered thee with silk.", "ylt": "And I clothe thee with embroidery, And I shoe thee with badger's skin, And I gird thee with fine linen, And I cover thee with figured silk.", "dra": "And I clothed thee with embroidery, and shod thee with violet coloured shoes: and I girded thee about with fine linen, and clothed thee with fine garments.", "bbe": "And I had you clothed with needlework, and put leather shoes on your feet, folding fair linen about you and covering you with silk.", "geneva": "I clothed thee also with broydred worke, and shod thee with badgers skin: and I girded thee about with fine linen, and I couered thee with silke.", "wycliffe": "And Y clothide thee with clothis of dyuerse colours, and Y schodde thee in iacynct, and Y girde thee with biys;", "rotherham": "And clothed thee with an embroidered dress, And sandalled thee in red leather, And wrapped thee about with fine linen, And put over thee a mantle of silk.", "darby": "and I clothed thee with embroidered work, and shod thee with badgers' skin, and I bound thee about with byssus, and covered thee with silk.", "twenty": "", "jps": "I clothed thee also with richly woven work, and shod thee with sealskin, and I wound fine linen about thy head, and covered thee with silk.", "acv": "I also clothed thee with embroidered work, and shod thee with a certain skin. And I girded thee around with fine linen, and covered thee with silk.", "anderson": "", "haweis": "", "noyes": "I clothed thee also with broidered work, and gave thee shoes of seal’s skin, and wrapped thee about with fine linen, and covered thee with silk.", "webster": "I clothed thee also with broidered work, and shod thee with badgers' skin, and I girded thee with fine linen, and I covered thee with silk.", "vulgate": "et vestivi te discoloribus et calciavi te ianthino et cinxi te bysso et indui te subtilibus;", "brenton": "And I clothed thee with embroidered garments, and clothed thee beneath with purple, and girded thee with fine linen, and clothed thee with silk,"}}, {"v": 11, "ref": "16:11", "o": "וָ/אֶעְדֵּ֖/ךְ עֶ֑דִי וָ/אֶתְּנָ֤/ה צְמִידִים֙ עַל יָדַ֔יִ/ךְ וְ/רָבִ֖יד עַל גְּרוֹנֵֽ/ךְ", "en": {"kjv": "I decked thee also with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.", "web": "I decked you with ornaments, and I put bracelets on your hands, and a chain on your neck.", "bsb": "I adorned you with jewelry, and I put bracelets on your wrists and a chain around your neck.", "asv": "And I decked thee with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.", "ylt": "And I adorn thee with adornments, And I give bracelets for thy hands, And a chain for thy neck.", "dra": "I decked thee also with ornaments, and put bracelets on thy hands, and a chain about thy neck.", "bbe": "And I made you fair with ornaments and put jewels on your hands and a chain on your neck.", "geneva": "I decked thee also with ornaments, and I put bracelets vpon thine handes, and a chaine on thy necke.", "wycliffe": "and Y clothide thee with sutil thingis, and Y ournede thee with ournement.", "rotherham": "Then decked I thee with ornaments, And put bracelets upon thy hands, And a neckchain upon thy throat;", "darby": "And I decked thee with ornaments, and I put bracelets upon thy hands, and a chain on thy neck;", "twenty": "", "jps": "I decked thee also with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.", "acv": "And I decked thee with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.", "anderson": "", "haweis": "", "noyes": "And I decked thee with ornaments, and put bracelets upon thy hands, and a chain upon thy neck.", "webster": "I decked thee also with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.", "vulgate": "et ornavi te ornamento et dedi armillas in manibus tuis et torquem circa collum tuum;", "brenton": "and decked thee also with ornaments, and put bracelets on thine hands, and a necklace on thy neck."}}, {"v": 12, "ref": "16:12", "o": "וָ/אֶתֵּ֥ן נֶ֨זֶם֙ עַל אַפֵּ֔/ךְ וַ/עֲגִילִ֖ים עַל אָזְנָ֑יִ/ךְ וַ/עֲטֶ֥רֶת תִּפְאֶ֖רֶת בְּ/רֹאשֵֽׁ/ךְ", "en": {"kjv": "And I put a jewel on thy forehead, and earrings in thine ears, and a beautiful crown upon thine head.", "web": "I put a ring on your nose, and earrings in your ears, and a beautiful crown on your head.", "bsb": "I put a ring in your nose, earrings on your ears, and a beautiful crown upon your head.", "asv": "And I put a ring upon thy nose, and ear-rings in thine ears, and a beautiful crown upon thy head.", "ylt": "And I give a ring for thy nose, And rings for thine ears, And a crown of beauty on thy head.", "dra": "And I put a jewel upon thy forehead and earrings in thy ears, and a beautiful crown upon thy head.", "bbe": "And I put a ring in your nose and ear-rings in your ears and a beautiful crown on your head.", "geneva": "And I put a frontlet vpon thy face, and earings in thine eares, and a beautifull crowne vpon thine head.", "wycliffe": "And Y yaf bies in thin hondis, and a wrethe aboute thi necke; and Y yaf a ryng on thi mouth, and cerclis to thin eeris, and a coroun of fairnesse in thin heed.", "rotherham": "And put a nose-jewel upon thy nose, And earrings in thine ears, And a crown of adorning, upon thy head.", "darby": "and I put a ring on thy nose, and earrings in thine ears, and a beautiful crown upon thy head.", "twenty": "", "jps": "And I put a ring upon thy nose, and earrings in thine ears, and a beautiful crown upon thy head.", "acv": "And I put a ring upon thy nose, and earrings in thine ears, and a beautiful crown upon thy head.", "anderson": "", "haweis": "", "noyes": "And I put a jewel in thy nostril, and ear-rings in thine ears, and a beautiful crown upon thy head.", "webster": "And I put a jewel on thy forehead, and ear-rings in thy ears, and a beautiful crown upon thy head.", "vulgate": "et dedi inaurem super os tuum et circulos auribus tuis et coronam decoris in capite tuo;", "brenton": "And I put a pendant on thy nostril, and rings in thine ears, and a crown of glory on thine head."}}, {"v": 13, "ref": "16:13", "o": "וַ/תַּעְדִּ֞י זָהָ֣ב וָ/כֶ֗סֶף וּ/מַלְבּוּשֵׁ/ךְ֙ ששי שֵׁ֤שׁ וָ/מֶ֨שִׁי֙ וְ/רִקְמָ֔ה סֹ֧לֶת וּ/דְבַ֛שׁ וָ/שֶׁ֖מֶן אכלתי אָכָ֑לְתְּ וַ/תִּ֨יפִי֙ בִּ/מְאֹ֣ד מְאֹ֔ד וַֽ/תִּצְלְחִ֖י לִ/מְלוּכָֽה", "en": {"kjv": "Thus wast thou decked with gold and silver; and thy raiment was of fine linen, and silk, and broidered work; thou didst eat fine flour, and honey, and oil: and thou wast exceeding beautiful, and thou didst prosper into a kingdom.", "web": "Thus you were decked with gold and silver; and your clothing was of fine linen, and silk, and embroidered work; you ate fine flour, and honey, and oil; and you were exceeding beautiful, and you prospered to royal estate.", "bsb": "So you were adorned with gold and silver, and your clothing was made of fine linen, silk, and embroidered cloth. You ate fine flour, honey, and oil. You became very beautiful and rose to be queen.", "asv": "Thus wast thou decked with gold and silver; and thy raiment was of fine linen, and silk, and broidered work; thou didst eat fine flour, and honey, and oil; and thou wast exceeding beautiful, and thou didst prosper unto royal estate.", "ylt": "And thou dost put on gold and silver, And thy clothing is fine linen, And figured silk and embroidery, Fine flour, and honey, and oil thou hast eaten, And thou art very very beautiful, And dost go prosperously to the kingdom.", "dra": "And thou wast adorned with gold, and silver, and wast clothed with fine linen, and embroidered work, and many colours: thou didst eat fine flour, and honey, and oil, and wast made exceeding beautiful: and wast advanced to be a queen.", "bbe": "So you were made beautiful with gold and silver; and your clothing was of the best linen and silk and needlework; your food was the best meal and honey and oil: and you were very beautiful.", "geneva": "Thus wast thou deckt with gold and siluer, and thy rayment was of fine linen, and silke, and broydred worke: thou didest eate fine floure, and honie and oyle, and thou wast very beautifull, and thou didest grow vp into a kingdome.", "wycliffe": "And thou were ourned with gold and siluer, and thou were clothid with biys and ray cloth with rounde ymagis, and many colours. Thou etist cleene flour of wheete, and hony, and oile, and thou were maad fair ful greetli; and thou encreessidist in to a rewme,", "rotherham": "Thus wast thou adorned with gold and silver, And thy raiment was of fine linen and silk and embroidered work, Fine flour and honey and oil, didst thou eat,— And so thou becamest exceedingly beautiful, And didst attain unto royalty.", "darby": "Thus wast thou decked with gold and silver, and thy raiment was byssus, and silk, and embroidered work. Thou didst eat fine flour, and honey, and oil; and thou becamest exceedingly beautiful, and thou didst prosper into a kingdom.", "twenty": "", "jps": "Thus wast thou decked with gold and silver; and thy raiment was of fine linen, and silk, and richly woven work; thou didst eat fine flour, and honey, and oil; and thou didst wax exceeding beautiful, and thou wast meet for royal estate.", "acv": "Thus thou were decked with gold and silver, and thy raiment was of fine linen, and silk, and embroidered work. Thou ate fine flour, and honey, and oil. And thou were very beautiful, and thou prospered to royalty.", "anderson": "", "haweis": "", "noyes": "Thus wast thou adorned with gold and silver, and thy raiment was of fine linen, and silk, and broidered work. Fine flour and honey and oil didst thou eat; and thou wast exceedingly beautiful, and didst prosper so as to become a queen.", "webster": "Thus wast thou decked with gold and silver; and thy raiment [was of] fine linen, and silk, and broidered work; thou didst eat fine flour, and honey, and oil: and thou wast exceeding beautiful, and thou didst prosper into a kingdom.", "vulgate": "et ornata es auro et argento et vestita es bysso et polymito et multicoloribus similam et mel et oleum comedisti et decora facta es vehementer nimis et profecisti in regnum;", "brenton": "So thou wast adorned with gold and silver; and thy raiment was of fine linen, and silk, and variegated work: thou didst eat fine flour, and oil, and honey, and didst become extremely beautiful."}}, {"v": 14, "ref": "16:14", "o": "וַ/יֵּ֨צֵא לָ֥/ךְ שֵׁ֛ם בַּ/גּוֹיִ֖ם בְּ/יָפְיֵ֑/ךְ כִּ֣י כָּלִ֣יל ה֗וּא בַּֽ/הֲדָרִ/י֙ אֲשֶׁר שַׂ֣מְתִּי עָלַ֔יִ/ךְ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And thy renown went forth among the heathen for thy beauty: for it was perfect through my comeliness, which I had put upon thee, saith the Lord God.", "web": "Your renown went out among the nations for your beauty; for it was perfect, through my majesty which I had put on you, says the Lord Yahweh.", "bsb": "Your fame spread among the nations on account of your beauty, for it was perfect in the splendor I bestowed on you, declares the Lord GOD.", "asv": "And thy renown went forth among the nations for thy beauty; for it was perfect, through my majesty which I had put upon thee, saith the Lord Jehovah.", "ylt": "And go forth doth thy name among nations, Because of thy beauty--for it is complete, In My honour that I have set upon thee, An affirmation of the Lord Jehovah.", "dra": "And thy renown went forth among the nations for thy beauty: for thou wast perfect through my beauty, which I had put upon thee, saith the Lord God.", "bbe": "You were so beautiful that the story of you went out into all nations; you were completely beautiful because of my glory which I had put on you, says the Lord.", "geneva": "And thy name was spred among the heathen for thy beautie: for it was perfite through my beautie which I had set vpon thee, saith the Lord God.", "wycliffe": "and thi name yede out in to hethene men for thi fairnesse; for thou were perfit in my fairnesse which Y hadde sett on thee, seith the Lord God.", "rotherham": "Then went forth thy fame among the nations. for thy beauty,- For perfect, it was—in my splendour which I had put upon thee, Declareth My Lord, Yahweh.", "darby": "And thy fame went forth among the nations for thy beauty; for it was perfect through my magnificence, which I had put upon thee, saith the Lord Jehovah.", "twenty": "", "jps": "And thy renown went forth among the nations for thy beauty; for it was perfect, through My splendour which I had put upon thee, saith the L-rd GOD.", "acv": "And thy renown went forth among the nations for thy beauty. For it was perfect, through my majesty which I had put upon thee, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And thy renown went forth among the nations for thy beauty; for it was perfect through my comeliness, which I had put upon thee, saith the Lord Jehovah.", "webster": "And thy renown went forth among the heathen for thy beauty: for it [was] perfect through my comeliness, which I had put upon thee, saith the Lord GOD.", "vulgate": "et egressum est nomen tuum in gentes propter speciem tuam quia perfecta eras in decore meo quem posueram super te dicit Dominus Deus;", "brenton": "And thy name went forth among the nations for thy beauty: because it was perfected with elegance, and in the comeliness which I put upon thee, saith the Lord."}}, {"v": 15, "ref": "16:15", "o": "וַ/תִּבְטְחִ֣י בְ/יָפְיֵ֔/ךְ וַ/תִּזְנִ֖י עַל שְׁמֵ֑/ךְ וַ/תִּשְׁפְּכִ֧י אֶת תַּזְנוּתַ֛יִ/ךְ עַל כָּל עוֹבֵ֖ר ל/וֹ יֶֽהִי", "en": {"kjv": "But thou didst trust in thine own beauty, and playedst the harlot because of thy renown, and pouredst out thy fornications on every one that passed by; his it was.", "web": "But you trusted in your beauty, and played the prostitute because of your renown, and poured out your prostitution on everyone who passed by; his it was.", "bsb": "But because of your fame, you trusted in your beauty and played the harlot. You lavished your favors on everyone who passed by, and your beauty was theirs for the asking.", "asv": "But thou didst trust in thy beauty, and playedst the harlot because of thy renown, and pouredst out thy whoredoms on every one that passed by; his it was.", "ylt": "And thou dost trust in thy beauty, And goest a-whoring because of thy renown, And dost pour out thy whoredoms On every passer by--to him it is.", "dra": "But trusting in thy beauty, thou playedst the harlot because of thy renown, and thou hast prostituted thyself to every passenger, to be his.", "bbe": "But you put your faith in the fact that you were beautiful, acting like a loose woman because you were widely talked of, and offering your cheap love to everyone who went by, whoever it might be.", "geneva": "Nowe thou didest trust in thine owne beautie, and playedst the harlot, because of thy renowne, and hast powred out thy fornications on euery one that passed by, thy desire was to him.", "wycliffe": "And thou haddist trist in thi fairnesse, and didist fornicacioun in thi name; and thou settidist forth thi fornicacioun to ech that passide forth, that thou schuldist be maad his.", "rotherham": "Then didst thou trust in thy beauty, And become unchaste, because of thy fame,- And didst pour out thine unchastity upon every passer-by, his it was!", "darby": "But thou didst confide in thy beauty, and playedst the harlot because of thy renown, and pouredst out thy whoredoms on every one that passed by: his it was.", "twenty": "", "jps": "But thou didst trust in thy beauty and play the harlot because of thy renown, and didst pour out thy harlotries on every one that passed by; his it was.", "acv": "But thou trusted in thy beauty, and played the harlot because of thy renown, and poured out thy whoredoms on everyone who passed by; his it was.", "anderson": "", "haweis": "", "noyes": "But thou didst trust in thy beauty, and didst play the harlot because of thy renown, and didst lavish thy fornications on every one that passed by; his was it.", "webster": "But thou didst trust in thy own beauty, and playedst the harlot because of thy renown, and pouredst out thy fornications on every one that passed by; his it was.", "vulgate": "et habens fiduciam in pulchritudine tua fornicata es in nomine tuo et exposuisti fornicationem tuam omni transeunti ut eius fieres;", "brenton": "Thou didst trust in thy beauty, and didst go a-whoring because of thy renown, and didst pour out thy fornication on every passer by."}}, {"v": 16, "ref": "16:16", "o": "וַ/תִּקְחִ֣י מִ/בְּגָדַ֗יִ/ךְ וַ/תַּֽעֲשִׂי לָ/ךְ֙ בָּמ֣וֹת טְלֻא֔וֹת וַ/תִּזְנִ֖י עֲלֵי/הֶ֑ם לֹ֥א בָא֖וֹת וְ/לֹ֥א יִהְיֶֽה", "en": {"kjv": "And of thy garments thou didst take, and deckedst thy high places with divers colours, and playedst the harlot thereupon: the like things shall not come, neither shall it be so.", "web": "You took of your garments, and made for yourselves high places decked with various colors, and played the prostitute on them. This shall not come, neither shall it be.", "bsb": "You took some of your garments and made colorful high places for yourself, and on them you prostituted yourself. Such things should not have happened; never should they have occurred!", "asv": "And thou didst take of thy garments, and madest for thee high places decked with divers colors, and playedst the harlot upon them: the like things shall not come, neither shall it be so.", "ylt": "And thou dost take of thy garments, And dost make to thee spotted high-places, And dost go a-whoring upon them, They are not coming in--nor shall it be!", "dra": "And taking of thy garments thou hast made thee high places sewed together on each side: and hast played the harlot upon them, as hath not been done before, nor shall be hereafter.", "bbe": "And you took your robes and made high places for yourself ornamented with every colour, acting like a loose woman on them, without shame or fear.", "geneva": "And thou didest take thy garments, and deckedst thine hie places with diuers colours, and playedst the harlot thereupon: the like thinges shall not come, neither hath any done so.", "wycliffe": "And thou tokist of my clothis, and madist to thee hiy thingis set aboute on ech side; and thou didist fornycacioun on tho, as it was not don, nether schal be don.", "rotherham": "Yea thou didst take of thy raiment and madest thee high places of hangings, And didst commit unchastity thereon,- Which ought not to have befallen And not to have come to pass.", "darby": "And of thy garments thou didst take, and madest for thyself high places decked with divers colours, and didst play the harlot thereupon: [the like] hath not come to pass, and shall be no more.", "twenty": "", "jps": "And thou didst take of thy garments, and didst make for thee high places decked with divers colours, and didst play the harlot upon them; the like things shall not come, neither shall it be so.", "acv": "And thou took of thy garments, and made high places for thee, decked with various colors, and played the harlot upon them, things which should not come, nor should it be.", "anderson": "", "haweis": "", "noyes": "And of thy garments thou didst take, and didst make thee high places, spread with divers colors, and didst play the harlot thereon, the like things to which shall not come to pass, neither shall they be.", "webster": "And of thy garments thou didst take, and deck thy high places with divers colors, and play the harlot upon them: [the like things] shall not come, neither shall it be [so].", "vulgate": "et sumens de vestimentis meis fecisti tibi excelsa hinc inde consuta et fornicata es super eis sicut non est factum neque futurum est;", "brenton": "And thou didst take of thy garments, and madest to thyself idols of needlework, and didst go a-whoring after them; therefore thou shalt never come in, nor shall the like take place."}}, {"v": 17, "ref": "16:17", "o": "וַ/תִּקְחִ֞י כְּלֵ֣י תִפְאַרְתֵּ֗/ךְ מִ/זְּהָבִ֤/י וּ/מִ/כַּסְפִּ/י֙ אֲשֶׁ֣ר נָתַ֣תִּי לָ֔/ךְ וַ/תַּעֲשִׂי לָ֖/ךְ צַלְמֵ֣י זָכָ֑ר וַ/תִּזְנִי בָֽ/ם", "en": {"kjv": "Thou hast also taken thy fair jewels of my gold and of my silver, which I had given thee, and madest to thyself images of men, and didst commit whoredom with them,", "web": "You also took your beautiful jewels of my gold and of my silver, which I had given you, and made for yourself images of men, and played the prostitute with them;", "bsb": "You also took the fine jewelry of gold and silver I had given you, and you made male idols with which to prostitute yourself.", "asv": "Thou didst also take thy fair jewels of my gold and of my silver, which I had given thee, and madest for thee images of men, and didst play the harlot with them;", "ylt": "And thou dost take thy beauteous vessels Of My gold and My silver that I gave to thee, And dost make to thee images of a male, And dost go a-whoring with them,", "dra": "And thou tookest thy beautiful vessels, of my gold, and my silver, which I gave thee, and thou madest thee images of men, and hast committed fornication with them.", "bbe": "And you took the fair jewels, my silver and gold which I had given to you, and made for yourself male images, acting like a loose woman with them;", "geneva": "Thou hast also taken thy faire iewels made of my golde and of my siluer, which I had giuen thee, and madest to thy selfe images of men, and didest commit whoredome with them,", "wycliffe": "And thou tokist the vessels of thi fairnesse, of my gold and of my siluer, which Y yaf to thee; and thou madist to thee ymagis of men, and didist fornycacioun in tho.", "rotherham": "But thou didst take thine adorning jewels Of my gold and of my silver which I had given thee, And didst make thee images of the male,— And didst act unchastely with them;", "darby": "And thou didst take thy fair jewels of my gold and of my silver, which I had given thee, and madest to thyself images of males, and didst commit fornication with them.", "twenty": "", "jps": "Thou didst also take thy fair jewels of My gold and of My silver, which I had given thee, and madest for thee images of men, and didst play the harlot with them;", "acv": "Thou also took thy fair jewels of my gold and of my silver, which I had given thee, and made for thee images of men, and played the harlot with them.", "anderson": "", "haweis": "", "noyes": "Thou didst take also thy fair jewels of my gold and my silver, which I gave thee, and didst make to thyself images of men, and didst commit fornication with them;", "webster": "Thou hast also taken thy fair jewels of my gold and of my silver, which I had given thee, and hast made to thyself images of men, and hast committed lewdness with them.", "vulgate": "et tulisti vasa decoris tui de auro meo et argento meo quae dedi tibi et fecisti tibi imagines masculinas et fornicata es in eis;", "brenton": "And thou tookest thy fair ornaments of my gold and of my silver, of what I gave thee, and thou madest to thyself male images, and thou didst commit whoredom with them."}}, {"v": 18, "ref": "16:18", "o": "וַ/תִּקְחִ֛י אֶת בִּגְדֵ֥י רִקְמָתֵ֖/ךְ וַ/תְּכַסִּ֑י/ם וְ/שַׁמְנִ/י֙ וּ/קְטָרְתִּ֔/י נתתי נָתַ֖תְּ לִ/פְנֵי/הֶֽם", "en": {"kjv": "And tookest thy broidered garments, and coveredst them: and thou hast set mine oil and mine incense before them.", "web": "and you took your embroidered garments, and covered them, and set my oil and my incense before them.", "bsb": "You took your embroidered garments to cover them, and you set My oil and incense before them.", "asv": "and thou tookest thy broidered garments, and coveredst them, and didst set mine oil and mine incense before them.", "ylt": "And dost take the garments of thy embroidery, And thou dost cover them, And My oil and My perfume thou hast set before them.", "dra": "And thou tookest thy garments of divers colours, and coveredst them: and settest my oil and my sweet incense before them.", "bbe": "And you took your robes of needlework for their clothing, and put my oil and my perfume before them.", "geneva": "And tookest thy broydred garments, and coueredst them: and thou hast set mine oyle and my perfume before them.", "wycliffe": "And thou tokist thi clothis of many colours, and thou were clothid in tho; and thou settidist myn oile and myn encence in the siyt of tho.", "rotherham": "And thou didst take thine embroidered raiment, and cover them,- And mine oil and mine incense, didst thou set before them;", "darby": "And thou tookest thine embroidered garments, and coveredst them; and thou didst set mine oil and mine incense before them.", "twenty": "", "jps": "and thou didst take thy richly woven garments and cover them, and didst set Mine oil and Mine incense before them.", "acv": "And thou took thy embroidered garments, and covered them, and set my oil and my incense before them.", "anderson": "", "haweis": "", "noyes": "and thou didst take thy broidered garments and cover them; and thou didst set mine oil and mine incense before them.", "webster": "And hast taken thy broidered garments, and covered them: and thou hast set my oil and my incense before them.", "vulgate": "et sumpsisti vestimenta tua multicoloria et vestita es eis et oleum meum et thymiama meum posuisti coram eis;", "brenton": "And thou didst take thy variegated apparel and didst clothe them, and thou didst set before them mine oil and mine incense."}}, {"v": 19, "ref": "16:19", "o": "וְ/לַחְמִ/י֩ אֲשֶׁר נָתַ֨תִּי לָ֜/ךְ סֹ֣לֶת וָ/שֶׁ֤מֶן וּ/דְבַשׁ֙ הֶֽאֱכַלְתִּ֔י/ךְ וּ/נְתַתִּ֧י/הוּ לִ/פְנֵי/הֶ֛ם לְ/רֵ֥יחַ נִיחֹ֖חַ וַ/יֶּ֑הִי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "My meat also which I gave thee, fine flour, and oil, and honey, wherewith I fed thee, thou hast even set it before them for a sweet savour: and thus it was, saith the Lord God.", "web": "My bread also which I gave you, fine flour, and oil, and honey, with which I fed you, you even set it before them for a pleasant aroma; and so it was, says the Lord Yahweh.", "bsb": "And you set before them as a pleasing aroma the food I had given you—the fine flour, oil, and honey that I had fed you. That is what happened, declares the Lord GOD.", "asv": "My bread also which I gave thee, fine flour, and oil, and honey, wherewith I fed thee, thou didst even set it before them for a sweet savor; and thus it was, saith the Lord Jehovah.", "ylt": "And My bread, that I gave to thee, Fine flour, and oil, and honey, that I caused thee to eat. Thou hast even set it before them, For a sweet fragrance--thus it is, An affirmation of the Lord Jehovah.", "dra": "And my bread which I gave thee, the fine flour, and oil, and honey, wherewith I fed thee, thou hast set before them for a sweet odour; and it was done, saith the Lord God.", "bbe": "And my bread which I gave you, the best meal and oil and honey which I gave you for your food, you put it before them for a sweet smell, says the Lord.", "geneva": "My meate also, which I gaue thee, as fine floure, oyle, and honie, wherewith I fedde thee, thou hast euen set it before them for a sweete sauour: thus it was, saith the Lord God.", "wycliffe": "And thou settidist my breed, which Y yaf to thee, flour of wheete, and oile, and hony, bi whiche Y nurschide thee, in the siyt of tho, in to odour of swetnesse; and it was don, seith the Lord God.", "rotherham": "And my food which I had given thee, Fine flour and oil and honey wherewith I fed thee, And didst set it before them for a satisfying odour Yea so it was,— Saith My Lord Yahweh.", "darby": "And my bread which I had given thee, the fine flour and the oil and the honey wherewith I fed thee, thou didst even set it before them for a sweet savour: thus it was, saith the Lord Jehovah.", "twenty": "", "jps": "My bread also which I gave thee, fine flour, and oil, and honey, wherewith I fed thee, thou didst even set it before them for a sweet savour, and thus it was; saith the L-rd GOD.", "acv": "My bread also which I gave thee, fine flour and oil and honey, with which I fed thee, thou even set it before them for a sweet savor, and thus it was, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "My food also, which I gave thee, fine flour and oil and honey, wherewith I fed thee, thou didst set it before them with a sweet savor; even thus it was, saith the Lord Jehovah.", "webster": "My provisions also which I gave thee, fine flour, and oil, and honey, [with which] I fed thee, thou hast even set before them for a sweet savor: and [thus] it was, saith the Lord GOD.", "vulgate": "et panem meum quem dedi tibi similam et oleum et mel quibus enutrivi te posuisti in conspectu eorum in odorem suavitatis et factum est ait Dominus Deus;", "brenton": "And thou tookest my bread which I gave thee, (yea I fed thee with fine flour and oil and honey) and didst set them before them for a sweet-smelling savour: yea, it was so, saith the Lord."}}, {"v": 20, "ref": "16:20", "o": "וַ/תִּקְחִ֞י אֶת בָּנַ֤יִ/ךְ וְ/אֶת בְּנוֹתַ֨יִ/ךְ֙ אֲשֶׁ֣ר יָלַ֣דְתְּ לִ֔/י וַ/תִּזְבָּחִ֥י/ם לָ/הֶ֖ם לֶ/אֱכ֑וֹל הַ/מְעַ֖ט מ/תזנת/ך מִ/תַּזְנוּתָֽיִ/ךְ", "en": {"kjv": "Moreover thou hast taken thy sons and thy daughters, whom thou hast borne unto me, and these hast thou sacrificed unto them to be devoured. Is this of thy whoredoms a small matter,", "web": "Moreover you have taken your sons and your daughters, whom you have borne to me, and you have sacrificed these to them to be devoured. Was your prostitution a small matter,", "bsb": "You even took the sons and daughters you bore to Me and sacrificed them as food to idols. Was your prostitution not enough?", "asv": "Moreover thou hast taken thy sons and thy daughters, whom thou hast borne unto me, and these hast thou sacrificed unto them to be devoured. Were thy whoredoms a small matter,", "ylt": "And thou dost take thy sons and thy daughters Whom thou hast born to Me, And dost sacrifice them to them for food. Is it a little thing because of thy whoredoms,", "dra": "And thou hast taken thy sons, and thy daughters, whom thou hast borne to me: and hast sacrificed the same to them to be devoured. Is thy fornication small?", "bbe": "And you took your sons and your daughters whom I had by you, offering even these to them to be their food. Was your loose behaviour so small a thing,", "geneva": "Moreouer thou hast taken thy sonnes and thy daughters, whome thou hast borne vnto me, and these hast thou sacrificed vnto them, to be deuoured: is this thy whoredome a small matter?", "wycliffe": "And thou tokist thi sones and thi douytris, whiche thou gendridist to me, and offridist to tho, for to be deuourid. Whether thi fornicacioun is litil?", "rotherham": "And thou didst take thy sons and thy daughters, Whom thou hadst borne unto me, And didst sacrifice them unto them to be devoured,- Is this of thine unchastity. a light thing?", "darby": "And thou didst take thy sons and thy daughters, whom thou hadst borne unto me, and these didst thou sacrifice unto them, to be devoured. Were thy whoredoms a small matter,", "twenty": "", "jps": "Moreover thou hast taken thy sons and thy daughters, whom thou hast borne unto Me, and these hast thou sacrificed unto them to be devoured. Were thy harlotries a small matter,", "acv": "Moreover thou have taken thy sons and thy daughters, whom thou have borne to me, and thou have sacrificed these to them to be devoured. Were thy whoredoms a small matter,", "anderson": "", "haweis": "", "noyes": "Moreover thou didst take thy sons and thy daughters, whom thou didst bear to me, and these didst thou sacrifice to them to be devoured. Was it not enough for thee to commit fornication,", "webster": "Moreover thou hast taken thy sons and thy daughters, whom thou hast borne to me, and these hast thou sacrificed to them to be devoured. [Is this] of thy lewdness a small matter,", "vulgate": "et tulisti filios tuos et filias tuas quas generasti mihi et immolasti eis ad devorandum numquid parva est fornicatio tua;", "brenton": "And thou tookest thy sons and thy daughters, whom thou borest, and didst sacrifice these to them to be destroyed. Thou didst go a-whoring as if that were little,"}}, {"v": 21, "ref": "16:21", "o": "וַֽ/תִּשְׁחֲטִ֖י אֶת בָּנָ֑/י וַֽ/תִּתְּנִ֔י/ם בְּ/הַעֲבִ֥יר אוֹתָ֖/ם לָ/הֶֽם", "en": {"kjv": "That thou hast slain my children, and delivered them to cause them to pass through the fire for them?", "web": "that you have slain my children, and delivered them up, in causing them to pass through the fire to them?", "bsb": "You slaughtered My children and delivered them up through the fire to idols.", "asv": "that thou hast slain my children, and delivered them up, in causing them to pass through the fire unto them?", "ylt": "That thou dost slaughter My sons, And dost give them up in causing them to pass over to them?", "dra": "Thou hast sacrificed and given my children to them, consecrating them by fire.", "bbe": "That you put my children to death and gave them up to go through the fire to them?", "geneva": "That thou hast slaine my children, and deliuered them to cause them to passe through fire for them?", "wycliffe": "Thou offridist my sones, and yauest hem, and halewidist to tho.", "rotherham": "Yea thou didst slay my children,— And didst deliver them up. that they should be caused to pass through the fire unto them.", "darby": "that thou didst slay my children and give them up in passing them over to them?", "twenty": "", "jps": "that thou hast slain My children, and delivered them up, in setting them apart unto them?", "acv": "that thou have slain my children, and delivered them up, in causing them to pass through the fire to them?", "anderson": "", "haweis": "", "noyes": "that thou didst slay my children, and deliver them up to cause them to pass through the fire to them?", "webster": "That thou hast slain my children, and delivered them to cause them to pass through [the fire] for them?", "vulgate": "immolantis filios meos et dedisti illos consecrans eis;", "brenton": "and didst slay thy children, and gavest them up in offering them to them for an expiation."}}, {"v": 22, "ref": "16:22", "o": "וְ/אֵ֤ת כָּל תּוֹעֲבֹתַ֨יִ/ךְ֙ וְ/תַזְנֻתַ֔יִ/ךְ לֹ֥א זכרתי זָכַ֖רְתְּ אֶת יְמֵ֣י נְעוּרָ֑יִ/ךְ בִּֽ/הְיוֹתֵ/ךְ֙ עֵרֹ֣ם וְ/עֶרְיָ֔ה מִתְבּוֹסֶ֥סֶת בְּ/דָמֵ֖/ךְ הָיִֽית", "en": {"kjv": "And in all thine abominations and thy whoredoms thou hast not remembered the days of thy youth, when thou wast naked and bare, and wast polluted in thy blood.", "web": "In all your abominations and your prostitution you have not remembered the days of your youth, when you were naked and bare, and were wallowing in your blood.", "bsb": "And in all your abominations and acts of prostitution, you did not remember the days of your youth when you were naked and bare, wallowing in your own blood.", "asv": "And in all thine abominations and thy whoredoms thou hast not remembered the days of thy youth, when thou wast naked and bare, and wast weltering in thy blood.", "ylt": "And with all thine abominations and thy whoredoms, Thou hast not remembered the days of thy youth, When thou wast naked and bare, Trodden down in thy blood thou wast!", "dra": "And after all thy abominations, and fornications, thou hast not remembered the days of thy youth, when thou wast naked, and full of confusion, trodden under foot in thy own blood.", "bbe": "And in all your disgusting and false behaviour you had no memory of your early days, when you were uncovered and without clothing, stretched out in your blood.", "geneva": "And in all thine abominations and whoredomes thou hast not remembred the dayes of thy youth, when thou wast naked and bare, and wast polluted in thy blood.", "wycliffe": "And aftir alle thin abhomynaciouns and fornicaciouns, thou bithouytist not on the daies of thi yong wexynge age, whanne thou were nakid, and ful of schenschipe, and were defoulid in thi blood.", "rotherham": "And in all thine abominations, and thine unchaste ways, thou rememberedst not the days of thy youth, When thou wast utterly naked. When thou wast thrusting about thee in thy blood!", "darby": "And in all thine abominations and thy whoredoms thou hast not remembered the days of thy youth, when thou wast naked and bare, when thou wast weltering in thy blood.", "twenty": "", "jps": "And in all thine abominations and thy harlotries thou hast not remembered the days of thy youth, when thou wast naked and bare, and wast wallowing in thy blood.", "acv": "And in all thine abominations and thy whoredoms thou have not remembered the days of thy youth when thou were naked and bare, and were weltering in thy blood.", "anderson": "", "haweis": "", "noyes": "And in all thine abominations and thy fornications, thou didst not remember the days of thy youth, when thou wast naked and bare, and in danger of being trampled under foot in thy blood.", "webster": "And in all thy abominations and thy deeds of lewdness thou hast not remembered the days of thy youth, when thou wast naked and bare, [and] wast polluted in thy blood.", "vulgate": "et post omnes abominationes tuas et fornicationes non es recordata dierum adulescentiae tuae quando eras nuda et confusione plena conculcata in sanguine tuo;", "brenton": "This is beyond all thy fornication, and thou didst not remember thine infancy, when thou wast naked and bare, and didst live though defiled in thy blood."}}, {"v": 23, "ref": "16:23", "o": "וַ/יְהִ֕י אַחֲרֵ֖י כָּל רָעָתֵ֑/ךְ א֣וֹי א֣וֹי לָ֔/ךְ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And it came to pass after all thy wickedness, (woe, woe unto thee! saith the Lord God;)", "web": "It has happened after all your wickedness, (woe, woe to you! says the Lord Yahweh),", "bsb": "Woe! Woe to you, declares the Lord GOD. And in addition to all your other wickedness,", "asv": "And it is come to pass after all thy wickedness (woe, woe unto thee! saith the Lord Jehovah),", "ylt": "And it cometh to pass, after all thy wickedness, (Woe, woe, to thee--an affirmation of the Lord Jehovah),", "dra": "And it came to pass after all thy wickedness (woe, woe to thee, saith the Lord God)", "bbe": "And it came about, after all your evil-doing, says the Lord,", "geneva": "And beside all thy wickednes (wo, wo vnto thee, saith the Lord God)", "wycliffe": "And after al thi malice, wo, wo bifelle to thee, seith the Lord God.", "rotherham": "And it came to pass after all thy wickedness, Woe! Woe! to thee, Exclaimeth My Lord Yahweh;", "darby": "And it came to pass after all thy wickedness (woe, woe unto thee! saith the Lord Jehovah),", "twenty": "", "jps": "And it came to pass after all thy wickedness--woe, woe unto thee! saith the L-rd GOD--", "acv": "And it has come to pass according to all thy wickedness, (woe, woe to thee! says the lord Jehovah),", "anderson": "", "haweis": "", "noyes": "And it came to pass, after all thy wickedness, (woe, woe to thee! saith the Lord Jehovah,)", "webster": "And it came to pass after all thy wickedness, (woe, woe to thee! saith the Lord GOD;)", "vulgate": "et accidit post omnem malitiam tuam vae vae tibi ait Dominus Deus;", "brenton": "And it came to pass after all thy wickedness, saith the Lord,"}}, {"v": 24, "ref": "16:24", "o": "וַ/תִּבְנִי לָ֖/ךְ גֶּ֑ב וַ/תַּעֲשִׂי לָ֥/ךְ רָמָ֖ה בְּ/כָל רְחֽוֹב", "en": {"kjv": "That thou hast also built unto thee an eminent place, and hast made thee an high place in every street.", "web": "that you have built for yourselves a vaulted place, and have made yourselves a lofty place in every street.", "bsb": "you built yourself a mound and made yourself a lofty shrine in every public square.", "asv": "that thou hast built unto thee a vaulted place, and hast made thee a lofty place in every street.", "ylt": "That thou dost build to thee an arch, And dost make to thee a high place in every broad place.", "dra": "That thou didst also build thee a common stew, and madest thee a brothel house in every street.", "bbe": "That you made for yourself an arched room in every open place.", "geneva": "Thou hast also built vnto thee an hie place, and hast made thee an hie place in euery streete.", "wycliffe": "And thou bildidist to thee a bordel hous, and madist to thee a place of hordom in alle stretis.", "rotherham": "That thou didst build thee a brothel,— and didst make thee a height in every broadway:", "darby": "that thou didst also build unto thee a place of debauchery, and didst make thee a high place in every street:", "twenty": "", "jps": "that thou hast built unto thee an eminent place, and hast made thee a lofty place in every street.", "acv": "that thou have built thyself a vaulted place, and have made thee a lofty place in every street.", "anderson": "", "haweis": "", "noyes": "that thou didst build for thee an arched place, and make thee a high place in every street;", "webster": "[That] thou hast also built to thee an eminent place, and hast made thee a high place in every street.", "vulgate": "et aedificasti tibi lupanar et fecisti tibi prostibulum in cunctis plateis;", "brenton": "that thou didst build thyself a house of fornication, and didst make thyself a public place in every street;"}}, {"v": 25, "ref": "16:25", "o": "אֶל כָּל רֹ֣אשׁ דֶּ֗רֶךְ בָּנִית֙ רָֽמָתֵ֔/ךְ וַ/תְּתַֽעֲבִי֙ אֶת יָפְיֵ֔/ךְ וַ/תְּפַשְּׂקִ֥י אֶת רַגְלַ֖יִ/ךְ לְ/כָל עוֹבֵ֑ר וַ/תַּרְבִּ֖י אֶת תזנת/ך תַּזְנוּתָֽיִ/ךְ", "en": {"kjv": "Thou hast built thy high place at every head of the way, and hast made thy beauty to be abhorred, and hast opened thy feet to every one that passed by, and multiplied thy whoredoms.", "web": "You have built your lofty place at the head of every way, and have made your beauty an abomination, and have opened your feet to everyone who passed by, and multiplied your prostitution.", "bsb": "At the head of every street you built your lofty shrines and degraded your beauty. With increasing promiscuity, you spread your legs to all who passed by.", "asv": "Thou hast built thy lofty place at the head of every way, and hast made thy beauty an abomination, and hast opened thy feet to every one that passed by, and multiplied thy whoredom.", "ylt": "At every head of the way thou hast built thy high place, And thou dost make thy beauty abominable, And dost open wide thy feet to every passer by, And dost multiply thy whoredoms,", "dra": "At every head of the way thou hast set up a sign of thy prostitution: and hast made thy beauty to be abominable: and hast prostituted thyself to every one that passed by, and hast multiplied thy fornications.", "bbe": "You put up your high places at the top of every street, and made the grace of your form a disgusting thing, opening your feet to everyone who went by, increasing your loose ways.", "geneva": "Thou hast built thine hie place at euery corner of the way, and hast made thy beautie to be abhorred: thou hast opened thy feete to euery one that passed by, and multiplied thy whoredome.", "wycliffe": "At ech heed of the weie thou bildidist a signe of thin hordom, and madist thi fairnesse abhomynable; and thou departidist thi feet to ech man passynge forth, and multepliedist thi fornicaciouns.", "rotherham": "At the head of every road, didst thou build thy height, And bring thy beauty into disgust, And open thy feet to every passer-by, So didst thou make thine unchaste ways to abound.", "darby": "thou didst build thy high place at every head of the way, and madest thy beauty to be abhorred, and thou didst open thy feet to every one that passed by, and multiply thy whoredom.", "twenty": "", "jps": "Thou hast built thy lofty place at every head of the way, and hast made thy beauty an abomination, and hast opened thy feet to every one that passed by, and multiplied thy harlotries.", "acv": "Thou have built thy lofty place at the head of every way, and have made thy beauty an abomination. And have opened thy feet to everyone who passed by, and multiplied thy whoredom.", "anderson": "", "haweis": "", "noyes": "at every head of the way didst thou build thy high place, and didst make thy beauty to be abhorred, and didst open thy feet to every one that passed by, and didst multiply thy fornications.", "webster": "Thou hast built thy high place at every head of the way, and hast made thy beauty to be abhorred, and hast prostituted thyself to every one that passed by, and multiplied thy lewd deeds.", "vulgate": "ad omne caput viae aedificasti signum prostitutionis tuae et abominabilem fecisti decorem tuum et divisisti pedes tuos omni transeunti et multiplicasti fornicationes tuas;", "brenton": "and on the head of every way thou didst set up thy fornications, and didst defile thy beauty, and didst open thy feet to every passer by, and didst multiply thy fornication."}}, {"v": 26, "ref": "16:26", "o": "וַ/תִּזְנִ֧י אֶל בְּנֵֽי מִצְרַ֛יִם שְׁכֵנַ֖יִ/ךְ גִּדְלֵ֣י בָשָׂ֑ר וַ/תַּרְבִּ֥י אֶת תַּזְנֻתֵ֖/ךְ לְ/הַכְעִיסֵֽ/נִי", "en": {"kjv": "Thou hast also committed fornication with the Egyptians thy neighbours, great of flesh; and hast increased thy whoredoms, to provoke me to anger.", "web": "You have also committed sexual immorality with the Egyptians, your neighbors, great of flesh; and have multiplied your prostitution, to provoke me to anger.", "bsb": "You prostituted yourself with your lustful neighbors, the Egyptians, and increased your promiscuity to provoke Me to anger.", "asv": "Thou hast also committed fornication with the Egyptians, thy neighbors, great of flesh; and hast multiplied thy whoredom, to provoke me to anger.", "ylt": "And dost go a-whoring unto sons of Egypt, Thy neighbours--great of appetite! And thou dost multiply thy whoredoms, To provoke Me to anger.", "dra": "And thou hast committed fornication with the Egyptians thy neighbours, men of large bodies, and hast multiplied thy fornications to provoke me.", "bbe": "And you went with the Egyptians, your neighbours, great of flesh; increasing your loose ways, moving me to wrath.", "geneva": "Thou hast also committed fornication with the Egyptians thy neighbours, which haue great members, and hast encreased thy whoredome, to prouoke me.", "wycliffe": "And thou didist fornicacioun with the sones of Egipt, thi neiyboris of grete fleischis, and thou multepliedist thi fornicacioun, to terre me to wraththe.", "rotherham": "Then didst thou extend thine unchaste acts unto the sons of Egypt—thy neighbour great of flesh,- And caused thine unchaste ways to abound provoking me to anger.", "darby": "And thou didst commit fornication with the Egyptians thy neighbours, great of flesh; and didst multiply thy whoredom to provoke me to anger.", "twenty": "", "jps": "Thou hast also played the harlot with the Egyptians, thy neighbours, great of flesh; and hast multiplied thy harlotry, to provoke Me.", "acv": "Thou have also committed fornication with the Egyptians, thy neighbors, great of flesh, and have multiplied thy whoredom, to provoke me to anger.", "anderson": "", "haweis": "", "noyes": "Thou hast also committed fornication with the Egyptians, thy neighbors, having great members, and hast multiplied thy fornications to provoke me to anger.", "webster": "Thou hast also committed fornication with the Egyptians thy neighbors, great of flesh; and hast multiplied thy lewd deeds, to provoke me to anger.", "vulgate": "et fornicata es cum filiis Aegypti vicinis tuis magnarum carnium et multiplicasti fornicationem tuam ad inritandum me;", "brenton": "And thou didst go a-whoring after the children of Egypt thy neighbors, great of flesh; and didst go a-whoring, often to provoke me to anger."}}, {"v": 27, "ref": "16:27", "o": "וְ/הִנֵּ֨ה נָטִ֤יתִי יָדִ/י֙ עָלַ֔יִ/ךְ וָ/אֶגְרַ֖ע חֻקֵּ֑/ךְ וָ/אֶתְּנֵ֞/ךְ בְּ/נֶ֤פֶשׁ שֹׂנְאוֹתַ֨יִ/ךְ֙ בְּנ֣וֹת פְּלִשְׁתִּ֔ים הַ/נִּכְלָמ֖וֹת מִ/דַּרְכֵּ֥/ךְ זִמָּֽה", "en": {"kjv": "Behold, therefore I have stretched out my hand over thee, and have diminished thine ordinary food, and delivered thee unto the will of them that hate thee, the daughters of the Philistines, which are ashamed of thy lewd way.", "web": "See therefore, I have stretched out my hand over you, and have diminished your portion, and delivered you to the will of those who hate you, the daughters of the Philistines, who are ashamed of your lewd way.", "bsb": "Therefore I stretched out My hand against you and reduced your portion. I gave you over to the desire of those who hate you, the daughters of the Philistines, who were ashamed of your lewd conduct.", "asv": "Behold therefore, I have stretched out my hand over thee, and have diminished thine ordinary food, and delivered thee unto the will of them that hate thee, the daughters of the Philistines, that are ashamed of thy lewd way.", "ylt": "And lo, I have stretched out My hand against thee, And I diminish thy portion, And give thee to the desire of those hating thee, The daughters of the Philistines, Who are ashamed of thy wicked way.", "dra": "Behold, I will stretch out my hand upon thee, and will take away thy justification: and I will deliver thee up to the will of the daughters of the Philistines that hate thee, that are ashamed of thy wicked way.", "bbe": "Now, then, my hand is stretched out against you, cutting down your fixed amount, and I have given you up to the desire of your haters, the daughters of the Philistines who are shamed by your loose ways.", "geneva": "Beholde, therefore I did stretche out mine hand ouer thee, and will diminish thine ordinarie, and deliuer thee vnto the will of them that hate thee, euen to the daughters of the Philistims, which are ashamed of thy wicked way.", "wycliffe": "Lo! Y schal stretch forth myn hond on thee, and Y schal take awei thi iustifiyng; and Y schal yyue thee in to the soulis of hem that haten thee, of the douytris of Palestyns, that ben aschamed in thi weie ful of greet trespas.", "rotherham": "Lo! therefore, I have stretched out my hand against thee, And diminished thine allotted portion,— And have delivered thee up unto the desire of them who hate thee The daughters of the Philistines, who are ashamed of thy lewd way.", "darby": "And behold, I stretched out my hand over thee, and diminished thine appointed portion; and I gave thee over unto the will of them that hate thee, the daughters of the Philistines, who were confounded at thy lewd way.", "twenty": "", "jps": "Behold, therefore I have stretched out My hand over thee, and have diminished thine allowance, and delivered thee unto the will of them that hate thee, the daughters of the Philistines, that are ashamed of thy lewd way.", "acv": "Behold therefore, I have stretched out my hand over thee, and have diminished thy portion, and delivered thee to the will of those who hate thee, the daughters of the Philistines, who are ashamed of thy lewd way.", "anderson": "", "haweis": "", "noyes": "Therefore, behold, I have stretched out my hand against thee, and have diminished thine allowance, and delivered thee to the will of them that hate thee, the daughters of the Philistines, who are ashamed of thy lewd way.", "webster": "Behold, therefore I have stretched out my hand over thee, and have diminished thy ordinary [food], and delivered thee to the will of them that hate thee, the daughters of the Philistines, who are ashamed of thy lewd way.", "vulgate": "ecce ego extendi manum meam super te et auferam ius tuum et dabo te in animam odientium te filiarum Palestinarum quae erubescunt in via tua scelerata;", "brenton": "And if I stretch out my hand against thee, then will I abolish thy statutes, and deliver thee up to the wills of them that hate thee, even to the daughters of the Philistines that turned thee aside from the way wherein thou sinned."}}, {"v": 28, "ref": "16:28", "o": "וַ/תִּזְנִי֙ אֶל בְּנֵ֣י אַשּׁ֔וּר מִ/בִּלְתִּ֖י שָׂבְעָתֵ֑/ךְ וַ/תִּזְנִ֕י/ם וְ/גַ֖ם לֹ֥א שָׂבָֽעַתְּ", "en": {"kjv": "Thou hast played the whore also with the Assyrians, because thou wast unsatiable; yea, thou hast played the harlot with them, and yet couldest not be satisfied.", "web": "You have played the prostitute also with the Assyrians, because you were insatiable; yes, you have played the prostitute with them, and yet you weren’t satisfied.", "bsb": "Then you prostituted yourself with the Assyrians, because you were not yet satisfied. Even after that, you were still not satisfied.", "asv": "Thou hast played the harlot also with the Assyrians, because thou wast insatiable; yea, thou hast played the harlot with them, and yet thou wast not satisfied.", "ylt": "And thou goest a-whoring unto sons of Asshur, Without thy being satisfied, And thou dost go a-whoring with them, And also--thou hast not been satisfied.", "dra": "Thou hast also committed fornication with the Assyrians, because thou wast not yet satisfied: and after thou hadst played the harlot with them, even so thou wast not contented.", "bbe": "And you went with the Assyrians, because of your desire which was without measure; you were acting like a loose woman with them, and still you had not enough.", "geneva": "Thou hast played the whore also with the Assyrians, because thou wast insaciable: yea, thou hast played the harlot with them, and yet couldest not be satisfied.", "wycliffe": "And thou didist fornicacioun with the sones of Assiriens, for thou were not fillid yit; and after that thou didist fornicacioun, nether so thou were fillid.", "rotherham": "Thou didst also extend thine unchastity unto the sons of Assyria, because thou wast insatiable. Yet though thou didst behave unchastely with them, yet even so couldst thou not be satisfied,", "darby": "And thou didst commit fornication with the Assyrians, because thou wast insatiable; yea, thou didst commit fornication with them, and yet couldest not be satisfied.", "twenty": "", "jps": "Thou hast played the harlot also with the Assyrians, without having enough; yea, thou hast played the harlot with them, and yet thou wast not satisfied.", "acv": "Thou have played the harlot also with the Assyrians, because thou were insatiable. Yea, thou have played the harlot with them, and yet thou were not satisfied.", "anderson": "", "haweis": "", "noyes": "Thou hast also committed fornication with the Assyrians, because thou wast insatiable; yea, thou hast played the harlot with them, and yet couldst not be satisfied.", "webster": "Thou hast played the harlot also with the Assyrians, because thou wast insatiable; yes, thou hast played the harlot with them, and yet couldst not be satisfied.", "vulgate": "et fornicata es in filiis Assyriorum eo quod necdum fueris expleta et postquam fornicata es nec sic es satiata;", "brenton": "And thou didst go a-whoring to the daughters of Assur, and not even thus wast thou satisfied; yea, thou didst go a-whoring, and wast not satisfied."}}, {"v": 29, "ref": "16:29", "o": "וַ/תַּרְבִּ֧י אֶת תַּזְנוּתֵ֛/ךְ אֶל אֶ֥רֶץ כְּנַ֖עַן כַּשְׂדִּ֑ימָ/ה וְ/גַם בְּ/זֹ֖את לֹ֥א שָׂבָֽעַתְּ", "en": {"kjv": "Thou hast moreover multiplied thy fornication in the land of Canaan unto Chaldea; and yet thou wast not satisfied herewith.", "web": "You have moreover multiplied your prostitution to the land of merchants, to Chaldea; and yet you weren’t satisfied with this.", "bsb": "So you extended your promiscuity to Chaldea, the land of merchants—but even with this you were not satisfied!", "asv": "Thou hast moreover multiplied thy whoredom unto the land of traffic, unto Chaldea; and yet thou wast not satisfied herewith.", "ylt": "And thou dost multiply thy whoredoms On the land of Canaan--toward Chaldea, And even with this thou hast not been satisfied.", "dra": "Thou hast also multiplied thy fornications in the land of Chanaan with the Chaldeans: and neither so wast thou satisfied.", "bbe": "And you went on in your loose ways, even as far as the land of Chaldaea, and still you had not enough.", "geneva": "Thou hast moreouer multiplied thy fornication from the land of Canaan vnto Caldea, and yet thou wast not satisfied herewith.", "wycliffe": "And thou multipliedist thi fornycacioun in the lond of Canaan with Caldeis, and nether so thou were fillid.", "rotherham": "Thou didst therefore cause thine unchaste ways to abound unto the land of Canaan as towards Chaldea. Yet even herewith, wast thou not satisfied.", "darby": "And thou didst multiply thy whoredom with the land of merchants, Chaldea, and yet thou wast not satisfied herewith.", "twenty": "", "jps": "Thou hast moreover multiplied thy harlotry with the land of traffic, even with Chaldea; and yet thou didst not have enough herewith.", "acv": "Thou have moreover multiplied thy whoredom to the land of traffic, to Chaldea, and yet thou were not satisfied with this.", "anderson": "", "haweis": "", "noyes": "Thou hast also multiplied thy fornication with the land of Canaan, even to Chaldaea; and yet wast thou not satisfied therewith.", "webster": "Thou hast moreover multiplied thy fornication in the land of Canaan to Chaldea; and yet with this thou wast not satisfied.", "vulgate": "et multiplicasti fornicationem tuam in terra Chanaan cum Chaldeis et nec sic satiata es;", "brenton": "And thou didst multiply thy covenants with the land of the Chaldeans; and not even with these wast thou satisfied."}}, {"v": 30, "ref": "16:30", "o": "מָ֤ה אֲמֻלָה֙ לִבָּתֵ֔/ךְ נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה בַּ/עֲשׂוֹתֵ/ךְ֙ אֶת כָּל אֵ֔לֶּה מַעֲשֵׂ֥ה אִשָּֽׁה זוֹנָ֖ה שַׁלָּֽטֶת", "en": {"kjv": "How weak is thine heart, saith the Lord God, seeing thou doest all these things, the work of an imperious whorish woman;", "web": "How weak is your heart, says the Lord Yahweh, since you do all these things, the work of an impudent prostitute;", "bsb": "How weak-willed is your heart, declares the Lord GOD, while you do all these things, the acts of a shameless prostitute!", "asv": "How weak is thy heart, saith the Lord Jehovah, seeing thou doest all these things, the work of an impudent harlot;", "ylt": "How weak is thy heart, An affirmation of the Lord Jehovah, In thy doing all these, The work of a domineering whorish woman.", "dra": "Wherein shall I cleanse thy heart, saith Lord God: seeing thou dost all these the works of a shameless prostitute?", "bbe": "How feeble is your heart, says the Lord, seeing that you do all these things, the work of a loose and overruling woman;", "geneva": "Howe weake is thine heart, saith the Lord God, seeing thou doest all these thinges, euen the worke of a presumptuous whorish woman?", "wycliffe": "In what thing schal Y clense thin herte, seith the Lord God, whanne thou doist alle these werkis of a womman an hoore, and gredi axere?", "rotherham": "How weak was thy heart! Exclaimeth My Lord Yahweh,— That thou couldst have done all these things, The doing of a lewd woman without shame:", "darby": "How weak is thy heart, saith the Lord Jehovah, seeing thou doest all these [things], the work of a whorish woman, under no restraint;", "twenty": "", "jps": "How weak is thy heart, saith the L-rd GOD, seeing thou doest all these things, the work of a wanton harlot;", "acv": "How weak is thy heart, says the lord Jehovah, seeing thou do all these things, the work of an impudent harlot,", "anderson": "", "haweis": "", "noyes": "How faint was thy heart, saith the Lord Jehovah, that thou didst all those things which an imperious whorish wife doeth,", "webster": "How weak is thy heart, saith the Lord GOD, seeing thou doest all these [things], the work of an imperious lewd woman;", "vulgate": "in quo mundabo cor tuum ait Dominus Deus cum facias omnia haec opera mulieris meretricis et procacis;", "brenton": "Why should I make a covenant with thy daughter, saith the Lord, while thou doest all these things, the works of a harlot? and thou hast gone a-whoring in a threefold degree with thy daughters."}}, {"v": 31, "ref": "16:31", "o": "בִּ/בְנוֹתַ֤יִ/ךְ גַּבֵּ/ךְ֙ בְּ/רֹ֣אשׁ כָּל דֶּ֔רֶךְ וְ/רָמָתֵ֥/ךְ עשיתי עָשִׂ֖ית בְּ/כָל רְח֑וֹב וְ/לֹא הייתי הָיִ֥ית כַּ/זּוֹנָ֖ה לְ/קַלֵּ֥ס אֶתְנָֽן", "en": {"kjv": "In that thou buildest thine eminent place in the head of every way, and makest thine high place in every street; and hast not been as an harlot, in that thou scornest hire;", "web": "in that you build your vaulted place at the head of every way, and make your lofty place in every street, and have not been as a prostitute, in that you scorn pay.", "bsb": "But when you built your mounds at the head of every street and made your lofty shrines in every public square, you were not even like a prostitute, because you scorned payment.", "asv": "in that thou buildest thy vaulted place at the head of every way, and makest thy lofty place in every street, and hast not been as a harlot, in that thou scornest hire.", "ylt": "In thy building thine arch at the head of every way, Thy high place thou hast made in every broad place, And--hast not been as a whore deriding a gift.", "dra": "Because thou hast built thy brothel house at the head of every way, and thou hast made thy high place in every street: and wast not as a harlot that by disdain enhanceth her price,", "bbe": "For you have made your arched room at the top of every street, and your high place in every open place; though you were not like a loose woman in getting together your payment.", "geneva": "In that thou buildest thine hie place in the corner of euery way, and makest thine hie place in euery streete, and hast not bene as an harlot that despiseth a reward,", "wycliffe": "For thou madist thi bordel hous in `the heed of ech weie, and thou madist thin hiy place in ech street; and thou were not maad as an hoore ful of anoiyng,", "rotherham": "That thou couldst have built thy brothel at the head of every road, And thy height, couldst have made in every broadway,- Yet becamest not as a harlot to lay claim to a harlot’s hire.", "darby": "in that thou buildest thy place of debauchery at the head of every way, and makest thy high place in every street! And thou hast not been as a harlot, in that thou scornest reward,", "twenty": "", "jps": "in that thou buildest thine eminent place in the head of every way, and makest thy lofty place in every street; and hast not been as a harlot that enhanceth her hire.", "acv": "in that thou build thy vaulted place at the head of every way, and make thy lofty place in every street. And have not even been as a harlot, in that thou scorn hire.", "anderson": "", "haweis": "", "noyes": "in that thou didst build thine arched place at the head of every way, and make thy high place in every street! Thou wast not like a harlot, who scoffeth at her hire,", "webster": "In that thou buildest thy eminent place in the head of every way, and makest thy high place in every street; and hast not been as a harlot, in that thou scornest hire;", "vulgate": "quia fabricasti lupanar tuum in capite omnis viae et excelsum tuum fecisti in omni platea nec facta es quasi meretrix fastidio augens pretium;", "brenton": "Thou hast built a house of harlotry in every top of a way, and hast set up thine high place in every street; and thou didst become as a harlot gathering hires."}}, {"v": 32, "ref": "16:32", "o": "הָ/אִשָּׁ֖ה הַ/מְּנָאָ֑פֶת תַּ֣חַת אִישָׁ֔/הּ תִּקַּ֖ח אֶת זָרִֽים", "en": {"kjv": "But as a wife that committeth adultery, which taketh strangers instead of her husband!", "web": "A wife who commits adultery! who takes strangers instead of her husband!", "bsb": "You adulterous wife! You receive strangers instead of your own husband!", "asv": "A wife that committeth adultery! that taketh strangers instead of her husband!", "ylt": "The wife who committeth adultery--Under her husband--doth receive strangers.", "dra": "But is an adulteress, that bringeth in strangers over her husband.", "bbe": "The untrue wife who takes strange lovers in place of her husband!", "geneva": "But as a wife that playeth the harlot, and taketh others for her husband:", "wycliffe": "encreessynge prijs, but as a womman auowtresse, that bryngith in aliens on hir hosebonde.", "rotherham": "A wife who committeth adultery, instead of her husband accepteth strangers.", "darby": "O adulterous wife, that taketh strangers instead of her husband.", "twenty": "", "jps": "Thou wife that committest adultery, that takest strangers instead of thy husband--", "acv": "A wife who commits adultery, who takes strangers instead of her husband!", "anderson": "", "haweis": "", "noyes": "but as an adulterous wife, that taketh strangers instead of her husband.", "webster": "[But as] a wife that committeth adultery, [who] taketh strangers instead of her husband!", "vulgate": "sed quasi mulier adultera quae super virum suum inducit alienos;", "brenton": "An adulteress resembles thee, taking rewards of her husband."}}, {"v": 33, "ref": "16:33", "o": "לְ/כָל זֹנ֖וֹת יִתְּנוּ נֵ֑דֶה וְ/אַ֨תְּ נָתַ֤תְּ אֶת נְדָנַ֨יִ/ךְ֙ לְ/כָל מְאַֽהֲבַ֔יִ/ךְ וַ/תִּשְׁחֳדִ֣י אוֹתָ֗/ם לָ/ב֥וֹא אֵלַ֛יִ/ךְ מִ/סָּבִ֖יב בְּ/תַזְנוּתָֽיִ/ךְ", "en": {"kjv": "They give gifts to all whores: but thou givest thy gifts to all thy lovers, and hirest them, that they may come unto thee on every side for thy whoredom.", "web": "They give gifts to all prostitutes; but you give your gifts to all your lovers, and bribe them, that they may come to you on every side for your prostitution.", "bsb": "Men give gifts to all their prostitutes, but you gave gifts to all your lovers. You bribed them to come to you from everywhere for your illicit favors.", "asv": "They give gifts to all harlots; but thou givest thy gifts to all thy lovers, and bribest them, that they may come unto thee on every side for thy whoredoms.", "ylt": "To all whores they give a gift, And--thou hast given thy gifts to all thy lovers, And dost bribe them to come in unto thee, From round about--in thy whoredoms.", "dra": "Gifts are given to all harlots: but thou hast given hire to all thy lovers, and thou hast given them gifts to come to thee from every side, to commit fornication with thee.", "bbe": "They give payment to all loose women: but you give rewards to your lovers, offering them payment so that they may come to you on every side for your cheap love.", "geneva": "They giue giftes to all other whores, but thou giuest giftes vnto all thy louers, and rewardest them, that they may come vnto thee on euery side for thy fornication.", "wycliffe": "Hiris ben youun to alle hooris, but thou hast youe hire to alle thi louyeris; and thou yauest to hem, that thei schulden entre to thee on ech side, to do fornycacioun with thee.", "rotherham": "To all harlots, they give a present,— But, thou, didst give thy presents to all thy lovers, And didst bribe them to come in unto thee from every side, in thine unchastity!", "darby": "They give rewards to all harlots; but thou gavest thy rewards to all thy lovers, and rewardedst them, that they might come unto thee on every side for thy whoredoms.", "twenty": "", "jps": "to all harlots gifts are given; but thou hast given thy gifts to all thy lovers, and hast bribed them to come unto thee from every side in thy harlotries.", "acv": "They give gifts to all harlots, but thou give thy gifts to all thy lovers, and bribe them, that they may come to thee on every side for thy whoredoms.", "anderson": "", "haweis": "", "noyes": "To all women that commit fornication men give a reward; but thou gavest thy gifts to all thy lovers, and hiredst them to come to thee from every side to commit fornication with thee.", "webster": "They give gifts to all lewd women: but thou givest thy gifts to all thy lovers, and hirest them, that they may come to thee on every side for thy lewdness.", "vulgate": "omnibus meretricibus dantur mercedes tu autem dedisti mercedes cunctis amatoribus tuis et donabas eis ut intrarent ad te undique ad fornicandum tecum;", "brenton": "She has even given rewards to all that went a-whoring after her, and thou hast given rewards to all thy lovers, yea, thou didst load them with rewards, that they should come to thee from every side for thy fornication."}}, {"v": 34, "ref": "16:34", "o": "וַ/יְהִי בָ֨/ךְ הֵ֤פֶךְ מִן הַ/נָּשִׁים֙ בְּ/תַזְנוּתַ֔יִ/ךְ וְ/אַחֲרַ֖יִ/ךְ לֹ֣א זוּנָּ֑ה וּ/בְ/תִתֵּ֣/ךְ אֶתְנָ֗ן וְ/אֶתְנַ֛ן לֹ֥א נִתַּן לָ֖/ךְ וַ/תְּהִ֥י לְ/הֶֽפֶךְ", "en": {"kjv": "And the contrary is in thee from other women in thy whoredoms, whereas none followeth thee to commit whoredoms: and in that thou givest a reward, and no reward is given unto thee, therefore thou art contrary.", "web": "You are different from other women in your prostitution, in that no one follows you to play the prostitute; and whereas you give hire, and no hire is given to you, therefore you are different.", "bsb": "So your prostitution is the opposite of that of other women: No one solicited your favors, and you paid a fee instead of receiving one; so you are the very opposite!", "asv": "And thou art different from other women in thy whoredoms, in that none followeth thee to play the harlot; and whereas thou givest hire, and no hire is given unto thee, therefore thou art different.", "ylt": "And the contrary is in thee from women in thy whoredoms, That after thee none doth go a-whoring; And in thy giving a gift, And a gift hath not been given to thee; And thou art become contrary.", "dra": "And it hath happened in thee contrary to the custom of women in thy fornications, and after thee there shall be no such fornication, for in that thou gavest rewards, and didst not take rewards, the contrary hath been done in thee.", "bbe": "And in your loose behaviour you are different from other women, for no one goes after you to make love to you: and because you give payment and no payment is given to you, in this you are different from them.", "geneva": "And the contrary is in thee from other women in thy fornications, neither the like fornication shall be after thee: for in that thou giuest a rewarde, and no reward is giuen vnto thee, therefore thou art contrary.", "wycliffe": "And it was don in thee ayens the custom of wymmen in thi fornycaciouns, and fornicacioun schal not be after thee; for in that that thou yauest hiris, and tokist not hiris, the contrarie was don in thee.", "rotherham": "And so there came about in thee, the reverse of women, in thine unchastity, In that they did not follow thee for purposes of lewdness,— And in that thou gavest a present while, no present, was given to thee So didst thou become, the reverse.", "darby": "And in thee is the contrary from [other] women, in thy whoredoms, in that none followeth thee to commit fornication; and whereas thou givest a reward, and no reward is given unto thee, so art thou contrary.", "twenty": "", "jps": "And the contrary is in thee from other women, in that thou didst solicit to harlotry, and wast not solicited; and in that thou givest hire, and no hire is given unto thee, thus thou art contrary.", "acv": "And thou are different from other women in thy whoredoms, in that none follows thee to play the harlot. And whereas thou give a wage, and no wage is given to thee, therefore thou are different.", "anderson": "", "haweis": "", "noyes": "Thou wast the reverse of other women in thy fornications. None followed after thee to commit fornication, but thou gavest the reward, and no reward was given thee,—therefore thou wast the reverse.", "webster": "And the contrary is in thee from [other] women in thy unlawful commerce, whereas none followeth thee to commit lewdness: and in that thou givest a reward, and no reward is given to thee, therefore thou art contrary.", "vulgate": "factumque in te est contra consuetudinem mulierum in fornicationibus tuis et post te non erit fornicatio in eo enim quod dedisti mercedes et mercedes non accepisti factum est in te contrarium;", "brenton": "And there has happened in thee perverseness in thy fornication beyond other women, and they have committed fornication with thee, in that thou givest hires over and above, and hires were not given to thee; and thus perverseness happened in thee."}}, {"v": 35, "ref": "16:35", "o": "לָ/כֵ֣ן זוֹנָ֔ה שִׁמְעִ֖י דְּבַר יְהוָֽה", "en": {"kjv": "Wherefore, O harlot, hear the word of the Lord:", "web": "Therefore, prostitute, hear Yahweh’s word:", "bsb": "Therefore, O prostitute, hear the word of the LORD!", "asv": "Wherefore, O harlot, hear the word of Jehovah:", "ylt": "Therefore, O whore, hear a word of Jehovah,", "dra": "Therefore, O harlot, hear the word of the Lord.", "bbe": "For this cause, O loose woman, give ear to the voice of the Lord:", "geneva": "Wherefore, O harlot, heare the worde of the Lord.", "wycliffe": "Therfor, thou hoore, here the word of the Lord.", "rotherham": "Therefore O harlot, hear thou the word of Yahweh;", "darby": "Therefore, O harlot, hear the word of Jehovah.", "twenty": "", "jps": "Wherefore, O harlot, hear the word of HaShem!", "acv": "Therefore, O harlot, hear the word of Jehovah.", "anderson": "", "haweis": "", "noyes": "Wherefore, O harlot, hear the word of Jehovah!", "webster": "Wherefore, O harlot, hear the word of the LORD:", "vulgate": "propterea meretrix audi verbum Domini;", "brenton": "Therefore, harlot, hear the word of the Lord:"}}, {"v": 36, "ref": "16:36", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהֹוִ֗ה יַ֣עַן הִשָּׁפֵ֤ךְ נְחֻשְׁתֵּ/ךְ֙ וַ/תִּגָּלֶ֣ה עֶרְוָתֵ֔/ךְ בְּ/תַזְנוּתַ֖יִ/ךְ עַל מְאַהֲבָ֑יִ/ךְ וְ/עַל֙ כָּל גִּלּוּלֵ֣י תוֹעֲבוֹתַ֔יִ/ךְ וְ/כִ/דְמֵ֣י בָנַ֔יִ/ךְ אֲשֶׁ֥ר נָתַ֖תְּ לָ/הֶֽם", "en": {"kjv": "Thus saith the Lord God; Because thy filthiness was poured out, and thy nakedness discovered through thy whoredoms with thy lovers, and with all the idols of thy abominations, and by the blood of thy children, which thou didst give unto them;", "web": "Thus says the Lord Yahweh, Because your filthiness was poured out, and your nakedness uncovered through your prostitution with your lovers; and because of all the idols of your abominations, and for the blood of your children, that you gave to them;", "bsb": "This is what the Lord GOD says: Because you poured out your wealth and exposed your nakedness in your promiscuity with your lovers and with all your detestable idols, and because of the blood of your children which you gave to them,", "asv": "Thus saith the Lord Jehovah, Because thy filthiness was poured out, and thy nakedness uncovered through thy whoredoms with thy lovers; and because of all the idols of thy abominations, and for the blood of thy children, that thou didst give unto them;", "ylt": "Thus said the Lord Jehovah: Because of thy brass being poured forth, And thy nakedness is revealed in thy whoredoms near thy lovers, And near all the idols of thy abominations, And according to the blood of thy sons, Whom thou hast given to them;", "dra": "Thus saith the Lord God: Because thy money hath been poured out, and thy shame discovered through thy fornications with thy lovers, and with the idols of thy abominations, by the blood of thy children whom thou gavest them:", "bbe": "This is what the Lord has said: Because your unclean behaviour was let loose and your body uncovered in your loose ways with your lovers and with your disgusting images, and for the blood of your children which you gave to them;", "geneva": "Thus sayeth the Lord God, Because thy shame was powred out, and thy filthinesse discouered through thy fornications with thy louers, and with all the idoles of thine abominations, and by the blood of thy children, which thou didest offer vnto them,", "wycliffe": "The Lord God seith these thingis, For thi riches is sched out, and thi schenschipe is schewid in thi fornicaciouns on thi louyeris, and on the idols of thin abhomynaciouns, in the blood of thi sones, whiche thou yauest to hem; lo!", "rotherham": "Thus saith My Lord Yahweh,— Because thy money, was poured out, and thy shame, was uncovered, in thine unchastity, unto thy lovers,—and unto all thine abominable manufactured gods, even as the blood of thy children, whom thou didst deliver up unto them,", "darby": "Thus saith the Lord Jehovah: Because thy money hath been poured out, and thy nakedness discovered through thy fornications with thy lovers, and with all the idols of thine abominations, and because of the blood of thy children which thou didst give unto them;", "twenty": "", "jps": "Thus saith the L-rd GOD: Because thy filthiness was poured out, and thy nakedness uncovered through thy harlotries with thy lovers; and because of all the idols of thy abominations, and for the blood of thy children, that thou didst give unto them;", "acv": "Thus says the lord Jehovah: Because thy filthiness was poured out, and thy nakedness uncovered through thy whoredoms with thy lovers, and because of all the idols of thy abominations, and for the blood of thy sons, that thou gave to them,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because thy treasure was poured out, and thy nakedness discovered for fornication before thy lovers, and all thine abominable idols, and because of the blood of thy children, which thou didst give to them,", "webster": "Thus saith the Lord GOD; Because thy filthiness was poured out, and thy nakedness exposed through thy carnal connection with thy lovers, and with all the idols of thy abominations, and by the blood of thy children, which thou didst give to them;", "vulgate": "haec dicit Dominus Deus quia effusum est aes tuum et revelata est ignominia tua in fornicationibus tuis super amatores tuos et super idola abominationum tuarum in sanguine filiorum tuorum quos dedisti eis;", "brenton": "Thus saith the Lord, Because thou hast poured forth thy money, therefore thy shame shall be discovered in thy harlotry with thy lovers, and with regard to all the imaginations of thine iniquities, and for the blood of thy children which thou hast given to them."}}, {"v": 37, "ref": "16:37", "o": "לָ֠/כֵן הִנְ/נִ֨י מְקַבֵּ֤ץ אֶת כָּל מְאַהֲבַ֨יִ/ךְ֙ אֲשֶׁ֣ר עָרַ֣בְתְּ עֲלֵי/הֶ֔ם וְ/אֵת֙ כָּל אֲשֶׁ֣ר אָהַ֔בְתְּ עַ֖ל כָּל אֲשֶׁ֣ר שָׂנֵ֑את וְ/קִבַּצְתִּי֩ אֹתָ֨/ם עָלַ֜יִ/ךְ מִ/סָּבִ֗יב וְ/גִלֵּיתִ֤י עֶרְוָתֵ/ךְ֙ אֲלֵ/הֶ֔ם וְ/רָא֖וּ אֶת כָּל עֶרְוָתֵֽ/ךְ", "en": {"kjv": "Behold, therefore I will gather all thy lovers, with whom thou hast taken pleasure, and all them that thou hast loved, with all them that thou hast hated; I will even gather them round about against thee, and will discover thy nakedness unto them, that they may see all thy nakedness.", "web": "therefore see, I will gather all your lovers, with whom you have taken pleasure, and all those who you have loved, with all those who you have hated; I will even gather them against you on every side, and will uncover your nakedness to them, that they may see all your nakedness.", "bsb": "therefore I will surely gather all the lovers with whom you found pleasure, all those you loved and all those you hated. I will gather them against you from all around and expose you before them, and they will see you completely naked.", "asv": "therefore behold, I will gather all thy lovers, with whom thou hast taken pleasure, and all them that thou hast loved, with all them that thou hast hated; I will even gather them against thee on every side, and will uncover thy nakedness unto them, that they may see all thy nakedness.", "ylt": "Therefore, lo, I am assembling all thy lovers, To whom thou hast been sweet, And all whom thou hast loved, Besides all whom thou hast hated; And I have assembled them by thee round about, And have revealed thy nakedness to them, And they have seen all thy nakedness.", "dra": "Behold, I will gather together all thy lovers with whom thou hast taken pleasure, and all whom thou hast loved, with all whom thou hast hated: and I will gather them together against thee on every side, and will discover thy shame in their sight, and they shall see all thy nakedness.", "bbe": "For this cause I will get together all your lovers with whom you have taken your pleasure, and all those to whom you have given your love, with all those who were hated by you; I will even make them come together against you on every side, and I will have you uncovered before them so that they may see your shame.", "geneva": "Beholde, therefore I wil gather all thy louers, with whom thou hast taken pleasure, and all them that thou hast loued, with al them that thou hast hated: I will euen gather them round about against thee, and will discouer thy filthines vnto them, that they may see all thy filthines.", "wycliffe": "Y schal gadere to gidere alle thi louyeris, with whiche thou were meddlid, and alle men whiche thou louedist, with alle men whiche thou hatidist; and Y schal gadere hem on thee on ech side, and Y schal make nakid thi schenschipe bifore hem, and thei schulen se al thi filthe.", "rotherham": "Therefore behold me! gathering together all thy lovers unto whom thou didst make thyself pleasant, Even all whom thou lovedst, With all whom thou hatedst,— Yea I will gather them together unto thee from every side And will uncover thy shame unto them, And they shall see all thy shame.", "darby": "therefore, behold, I will gather all thy lovers with whom thou hast taken pleasure, and all that thou hast loved, with all that thou hast hated, — I will even gather them round about against thee, and will discover thy nakedness unto them, that they may see all thy nakedness.", "twenty": "", "jps": "therefore behold, I will gather all thy lovers, unto whom thou hast been pleasant, and all them that thou hast loved, with all them that thou hast hated; I will even gather them against thee from every side, and will uncover thy nakedness unto them, that they may see all thy nakedness.", "acv": "therefore, behold, I will gather all thy lovers, with whom thou have taken pleasure, and all those whom thou have loved, with all those whom thou have hated, I will even gather them against thee on every side. And I will uncover thy nakedness to them, that they may see all thy nakedness.", "anderson": "", "haweis": "", "noyes": "therefore, behold, I will gather all thy lovers, to whom thou wast pleasing, all them that thou hast loved, with all them that thou hast hated, I will gather them against thee round about, and will uncover thy nakedness to them, that they may see all thy nakedness.", "webster": "Behold therefore, I will gather all thy lovers, with whom thou hast taken pleasure, and all [them] that thou hast loved, with all [them] that thou hast hated; I will even gather them on every side against thee, and will uncover thy nakedness to them, that they may see all thy nakedness.", "vulgate": "ecce ego congregabo omnes amatores tuos quibus commixta es et omnes quos dilexisti cum universis quos oderas et congregabo eos super te undique et nudabo ignominiam tuam coram eis et videbunt omnem turpitudinem tuam;", "brenton": "Therefore, behold, I will gather all thy lovers with whom thou hast consorted, and all whom thou hast loved, with all whom thou didst hate; and I will gather them against thee round about, and will expose thy wickedness to them, and they shall see all thy shame."}}, {"v": 38, "ref": "16:38", "o": "וּ/שְׁפַטְתִּי/ךְ֙ מִשְׁפְּטֵ֣י נֹאֲפ֔וֹת וְ/שֹׁפְכֹ֖ת דָּ֑ם וּ/נְתַתִּ֕י/ךְ דַּ֥ם חֵמָ֖ה וְ/קִנְאָֽה", "en": {"kjv": "And I will judge thee, as women that break wedlock and shed blood are judged; and I will give thee blood in fury and jealousy.", "web": "I will judge you, as women who break wedlock and shed blood are judged; and I will bring on you the blood of wrath and jealousy.", "bsb": "And I will sentence you to the punishment of women who commit adultery and those who shed blood; so I will bring upon you the wrath of your bloodshed and jealousy.", "asv": "And I will judge thee, as women that break wedlock and shed blood are judged; and I will bring upon thee the blood of wrath and jealousy.", "ylt": "And I have judged thee--judgments of adulteresses, And of women shedding blood, And have given thee blood, fury, and jealousy.", "dra": "And I will judge thee as adulteresses, and they that shed blood are judged: and I will give thee blood in fury and jealousy.", "bbe": "And you will be judged by me as women are judged who have been untrue to their husbands and have taken life; and I will let loose against you passion and bitter feeling.", "geneva": "And I wil iudge thee after ye maner of them that are harlots, and of them that shead blood, and I wil giue thee the blood of wrath and ielousie.", "wycliffe": "And Y schal deme thee bi the domes of auoutressis, and schedinge out blood;", "rotherham": "So will I judge thee. with the judgments meted out to adulteresses and shedders of blood,- And will repay thee with the blood of indignation and jealousy;", "darby": "And I will judge thee with the judgments of women that commit adultery and shed blood; and I will give thee up to the blood of fury and jealousy;", "twenty": "", "jps": "And I will judge thee, as women that break wedlock and shed blood are judged; and I will bring upon thee the blood of fury and jealousy.", "acv": "And I will judge thee, as women who break wedlock and shed blood are judged. And I will bring upon thee the blood of wrath and jealousy.", "anderson": "", "haweis": "", "noyes": "And I will judge thee as women that break wedlock and shed blood are judged, and I will cause thy blood to flow in fury and jealousy.", "webster": "And I will judge thee, as women that break wedlock and shed blood are judged; and I will give thee blood in fury and jealousy.", "vulgate": "et iudicabo te iudiciis adulterarum et effundentium sanguinem et dabo te in sanguinem furoris et zeli;", "brenton": "And I will be avenged on thee with the vengeance of an adulteress, and I will bring upon thee blood of fury and jealousy."}}, {"v": 39, "ref": "16:39", "o": "וְ/נָתַתִּ֨י אוֹתָ֜/ךְ בְּ/יָדָ֗/ם וְ/הָרְס֤וּ גַבֵּ/ךְ֙ וְ/נִתְּצ֣וּ רָמֹתַ֔יִ/ךְ וְ/הִפְשִׁ֤יטוּ אוֹתָ/ךְ֙ בְּגָדַ֔יִ/ךְ וְ/לָקְח֖וּ כְּלֵ֣י תִפְאַרְתֵּ֑/ךְ וְ/הִנִּיח֖וּ/ךְ עֵירֹ֥ם וְ/עֶרְיָֽה", "en": {"kjv": "And I will also give thee into their hand, and they shall throw down thine eminent place, and shall break down thy high places: they shall strip thee also of thy clothes, and shall take thy fair jewels, and leave thee naked and bare.", "web": "I will also give you into their hand, and they shall throw down your vaulted place, and break down your lofty places; and they shall strip you of your clothes, and take your beautiful jewels; and they shall leave you naked and bare.", "bsb": "Then I will deliver you into the hands of your lovers, and they will level your mounds and tear down your lofty shrines. They will strip off your clothes, take your fine jewelry, and leave you naked and bare.", "asv": "I will also give thee into their hand, and they shall throw down thy vaulted place, and break down thy lofty places; and they shall strip thee of thy clothes, and take thy fair jewels; and they shall leave thee naked and bare.", "ylt": "And I have given thee into their hand, And they have thrown down thine arch, And they have broken down thy high places, And they have stript thee of thy garments, And they have taken thy beauteous vessels, And they have left thee naked and bare.", "dra": "And I will deliver thee into their hands, and they shall destroy thy brothel house, and throw down thy stews: and they shall strip thee of thy garments, and shall take away the vessels of thy beauty: and leave thee naked, and full of disgrace.", "bbe": "I will give you into their hands, and your arched room will be overturned and your high places broken down; they will take your clothing off you and take away your fair jewels: and when they have done, you will be uncovered and shamed.", "geneva": "I will also giue thee into their handes, and they shall destroy thine hie place, and shall breake downe thine hie places. they shall strippe thee also out of thy clothes, and shall take thy faire iewels, and leaue thee naked and bare.", "wycliffe": "and Y schal yyue thee in to the blood of strong veniaunce, and of feruour. And Y schal yyue thee in to the hondis of hem, and thei schulen destrie thi bordel hous, and thei schulen destrie the place of thin hordom; and thei schulen make thee nakid of thi clothis, and thei schulen take awei the vessels of thi fairnesse, and thei schulen forsake thee nakid, and ful of schenschipe.", "rotherham": "And will deliver thee into their hand. And they shall pull down thy brothel And break in pieces thy heights, And strip thee of thy raiment, And take away thine adorning jewels,- And leave thee utterly naked.", "darby": "and I will give thee into their hand, and they shall throw down thy place of debauchery, and shall break down thy high places; and they shall strip thee of thy garments, and shall take thy fair jewels, and leave thee naked and bare.", "twenty": "", "jps": "I will also give thee into their hand, and they shall throw down thine eminent place, and break down thy lofty places; and they shall strip thee of thy clothes, and take thy fair jewels; and they shall leave thee naked and bare.", "acv": "I will also give thee into their hand, and they shall throw down thy vaulted place, and break down thy lofty places. And they shall strip thee of thy clothes, and take thy fair jewels, and they shall leave thee naked and bare.", "anderson": "", "haweis": "", "noyes": "And I will give thee into their hand, and they shall throw down thine arched place, and break down thy high places. They shall also strip thee of thy clothes, and leave thee naked and bare.", "webster": "And I will also give thee into their hand, and they shall throw down thy eminent place, and shall break down thy high places: they shall strip thee also of thy clothes, and shall take thy fair jewels, and leave thee naked and bare.", "vulgate": "et dabo te in manus eorum et destruent lupanar tuum et demolientur prostibulum tuum et denudabunt te vestimentis tuis et auferent vasa decoris tui et derelinquent te nudam plenamque ignominia;", "brenton": "And I will deliver thee into their hands, and they shall break down thy house of harlotry, and destroy thine high place; and they shall strip thee of thy garments, and shall take thy proud ornaments, and leave thee naked and bare."}}, {"v": 40, "ref": "16:40", "o": "וְ/הֶעֱל֤וּ עָלַ֨יִ/ךְ֙ קָהָ֔ל וְ/רָגְמ֥וּ אוֹתָ֖/ךְ בָּ/אָ֑בֶן וּ/בִתְּק֖וּ/ךְ בְּ/חַרְבוֹתָֽ/ם", "en": {"kjv": "They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "web": "They shall also bring up a company against you, and they shall stone you with stones, and thrust you through with their swords.", "bsb": "They will bring a mob against you, who will stone you and cut you to pieces with their swords.", "asv": "They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "ylt": "And have caused an assembly to come up against thee, And stoned thee with stones, And thrust thee through with their swords,", "dra": "And they shall bring upon thee a multitude, and they shall stone thee with stones, and shall slay thee with their swords.", "bbe": "And they will get together a meeting against you, stoning you with stones and wounding you with their swords.", "geneva": "They shall also bring vp a company against thee, and they shall stone thee with stones, and thrust thee through with their swordes.", "wycliffe": "And thei schulen bringe on thee a multitude, and thei schulen stoon thee with stoonys, and thei schulen sle thee with her swerdis.", "rotherham": "Then will they bring up against thee a gathered host, And they will stone thee with stones,- And cut thee to pieces with their swords;", "darby": "And they shall bring up an assemblage against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "twenty": "", "jps": "They shall also bring up an assembly against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "acv": "They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "anderson": "", "haweis": "", "noyes": "They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords;", "webster": "They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords.", "vulgate": "et adducent super te multitudinem et lapidabunt te lapidibus et trucidabunt te gladiis suis;", "brenton": "And they shall bring multitudes upon thee, and they shall stone thee with stones, and pierce thee with their swords."}}, {"v": 41, "ref": "16:41", "o": "וְ/שָׂרְפ֤וּ בָתַּ֨יִ/ךְ֙ בָּ/אֵ֔שׁ וְ/עָשׂוּ בָ֣/ךְ שְׁפָטִ֔ים לְ/עֵינֵ֖י נָשִׁ֣ים רַבּ֑וֹת וְ/הִשְׁבַּתִּי/ךְ֙ מִ/זּוֹנָ֔ה וְ/גַם אֶתְנַ֖ן לֹ֥א תִתְּנִי עֽוֹד", "en": {"kjv": "And they shall burn thine houses with fire, and execute judgments upon thee in the sight of many women: and I will cause thee to cease from playing the harlot, and thou also shalt give no hire any more.", "web": "They shall burn your houses with fire, and execute judgments on you in the sight of many women; and I will cause you to cease from playing the prostitute, and you shall also give no hire any more.", "bsb": "Then they will burn down your houses and execute judgment against you in the sight of many women. I will put an end to your prostitution, and you will never again pay your lovers.", "asv": "And they shall burn thy houses with fire, and execute judgments upon thee in the sight of many women; and I will cause thee to cease from playing the harlot, and thou shalt also give no hire any more.", "ylt": "And burnt thy houses with fire, And done in thee judgments before the eyes of many women, And I have caused thee to cease from going a-whoring, And also a gift thou givest no more.", "dra": "And they shall burn thy houses with fire, and shall execute judgments upon thee in the sight of many women: and thou shalt cease from fornication, and shalt give no hire any more.", "bbe": "And they will have you burned with fire, sending punishments on you before the eyes of great numbers of women; and I will put an end to your loose ways, and you will no longer give payment.", "geneva": "And they shall burne vp thine houses with fire, and execute iudgements vpon thee in the sight of many women: and I will cause thee to cease from playing the harlot, and thou shalt giue no reward any more.", "wycliffe": "And thei schulen brenne thin housis with fier, and thei schulen make domes in thee, bifor the iyen of ful many wymmen; and thou schalt ceese to do fornicacioun, and thou schalt no more yyue hiris.", "rotherham": "And burn up thy houses with fire, And execute upon thee judgments before the eyes of many women,—So will I cause thee to cease from acting unchastely, Moreover also a present, shalt thou not give any more.", "darby": "And they shall burn thy houses with fire, and execute judgments upon thee in the sight of many women; and I will cause thee to cease from being a harlot, and thou also shalt give no more any reward.", "twenty": "", "jps": "And they shall burn thy houses with fire, and execute judgments upon thee in the sight of many women; and I will cause thee to cease from playing the harlot, and thou shalt also give no hire any more.", "acv": "And they shall burn thy houses with fire, and execute judgments upon thee in the sight of many women. And I will cause thee to cease from playing the harlot, and thou shall also give no wage any more.", "anderson": "", "haweis": "", "noyes": "and they shall burn thine houses with fire, and execute judgments upon thee in the sight of many women; and I will cause thee to cease from playing the harlot, and thou shalt give hire no more.", "webster": "And they shall burn thy houses with fire, and execute judgments upon thee in the sight of many women: and I will cause thee to cease from playing the harlot, and thou also shalt give no hire any more.", "vulgate": "et conburent domos tuas igni et facient in te iudicia in oculis mulierum plurimarum et desines fornicari et mercedes ultra non dabis;", "brenton": "And they shall burn thine houses with fire, and shall execute vengeance on thee in the sight of many women: and I will turn thee back from harlotry, and I will no more give thee rewards."}}, {"v": 42, "ref": "16:42", "o": "וַ/הֲנִחֹתִ֤י חֲמָתִ/י֙ בָּ֔/ךְ וְ/סָ֥רָה קִנְאָתִ֖/י מִמֵּ֑/ךְ וְ/שָׁ֣קַטְתִּ֔י וְ/לֹ֥א אֶכְעַ֖ס עֽוֹד", "en": {"kjv": "So will I make my fury toward thee to rest, and my jealousy shall depart from thee, and I will be quiet, and will be no more angry.", "web": "So will I cause my wrath toward you to rest, and my jealousy shall depart from you, and I will be quiet, and will be no more angry.", "bsb": "So I will lay to rest My wrath against you, and My jealousy will turn away from you. Then I will be calm and no longer angry.", "asv": "So will I cause my wrath toward thee to rest, and my jealousy shall depart from thee, and I will be quiet, and will be no more angry.", "ylt": "And I have caused My fury against thee to rest, And My jealousy hath turned aside from thee, And I have been quiet, and I am not angry any more.", "dra": "And my indignation shall rest in thee: and my jealousy shall depart from thee, and I will cease and be angry no more.", "bbe": "And the heat of my wrath against you will have an end, and my bitter feeling will be turned away from you, and I will be quiet and will be angry no longer.", "geneva": "So will I make my wrath towarde thee to rest, and my ielousie shall depart from thee, and I will cease and be no more angrie.", "wycliffe": "And myn indignacioun schal reste in thee, and my feruent loue schal be takun awei fro thee; and Y schal reste, and Y schal no more be wrooth,", "rotherham": "So will I let mine indignation find rest in thee, And my jealousy shall depart from thee,—And I will be quiet, and not be provoked any more.", "darby": "And I will appease my fury against thee, and my jealousy shall depart from thee; and I will be quiet, and will be no more angry.", "twenty": "", "jps": "So will I satisfy My fury upon thee, and My jealousy shall depart from thee, and I will be quiet, and will be no more angry.", "acv": "So I will cause my wrath toward thee to rest, and my jealousy shall depart from thee, and I will be quiet, and will no more be angry.", "anderson": "", "haweis": "", "noyes": "So will I make my fury toward thee to rest, and my jealousy shall depart from thee; and I will be quiet, and will be no more angry.", "webster": "So will I make my fury towards thee to rest, and my jealousy shall depart from thee, and I will be quiet, and will be no more angry.", "vulgate": "et requiescet indignatio mea in te et auferetur zelus meus a te et quiescam nec irascar amplius;", "brenton": "So will I slacken my fury against thee, and my jealousy shall be removed from thee, and I will rest, and be no more careful for thee."}}, {"v": 43, "ref": "16:43", "o": "יַ֗עַן אֲשֶׁ֤ר לֹֽא זכרתי זָכַרְתְּ֙ אֶת יְמֵ֣י נְעוּרַ֔יִ/ךְ וַ/תִּרְגְּזִי לִ֖/י בְּ/כָל אֵ֑לֶּה וְ/גַם אֲנִ֨י הֵ֜א דַּרְכֵּ֣/ךְ בְּ/רֹ֣אשׁ נָתַ֗תִּי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה וְ/לֹ֤א עשיתי עָשִׂית֙ אֶת הַ/זִּמָּ֔ה עַ֖ל כָּל תּוֹעֲבֹתָֽיִ/ךְ", "en": {"kjv": "Because thou hast not remembered the days of thy youth, but hast fretted me in all these things; behold, therefore I also will recompense thy way upon thine head, saith the Lord God: and thou shalt not commit this lewdness above all thine abominations.", "web": "Because you have not remembered the days of your youth, but have raged against me in all these things; therefore, behold, I also will bring your way on your head, says the Lord Yahweh: and you shall not commit this lewdness with all your abominations.", "bsb": "Because you did not remember the days of your youth, but enraged Me with all these things, I will surely bring your deeds down upon your own head, declares the Lord GOD. Have you not committed this lewdness on top of all your other abominations?", "asv": "Because thou hast not remembered the days of thy youth, but hast raged against me in all these things; therefore, behold, I also will bring thy way upon thy head, saith the Lord Jehovah: and thou shalt not commit this lewdness with all thine abominations.", "ylt": "Because thou hast not remembered the days of thy youth, And dost give trouble to Me in all these, Lo, even I also thy way at first gave up, An affirmation of the Lord Jehovah, And I did not this thought for all thine abominations.", "dra": "Because thou hast not remembered the days of thy youth, but hast provoked me in all these things: wherefore I also have turned all thy ways upon thy head, saith the Lord God, and I have not done according to thy wicked deeds in all thy abominations.", "bbe": "Because you have not kept in mind the days when you were young, but have been troubling me with all these things; for this reason I will make the punishment of your ways come on your head, says the Lord, because you have done this evil thing in addition to all your disgusting acts.", "geneva": "Because thou hast not remembred the dayes of thy youth, but hast prouoked me with all these things, behold, therefore I also haue brought thy way vpon thine head, sayeth the Lord God: yet hast not thou had consideration of all thine abominations.", "wycliffe": "for thou haddist not mynde on the daies of thi yong wexynge age, and thou terridist me to ire in alle these thingis. Wherfor and Y yaf thi weies in thin heed, seith the Lord God, and Y dide not aftir thi grete trespassis, in alle these thin abhomynaciouns.", "rotherham": "Because thou hast not remembered the days of thy youth, But hast enraged me with all these things Therefore also behold! I thy way, upon thine own head, will place Declareth My Lord Yahweh, And thou shalt not commit a crime above all thine abominations", "darby": "Because thou hast not remembered the days of thy youth, but hast raged against me in all these [things], behold, therefore, I also will recompense thy way upon [thy] head, saith the Lord Jehovah, and thou shalt not commit this lewdness besides all thine abominations.", "twenty": "", "jps": "Because thou hast not remembered the days of thy youth, but hast fretted Me in all these things; lo, therefore I also will bring thy way upon thy head, saith the L-rd GOD; or hast thou not committed this lewdness above all thine abominations?", "acv": "Because thou have not remembered the days of thy youth, but have raged against me in all these things, therefore, behold, I also will bring thy way upon thy head, says the lord Jehovah. And thou shall not commit this lewdness with all thine abominations.", "anderson": "", "haweis": "", "noyes": "Because thou hast not remembered the days of thy youth, but hast raged against me in all these things, therefore I also will recompense thy way upon thy head, saith the Lord Jehovah, so that thou shalt not commit this wickedness in addition to all thy abominations.", "webster": "Because thou hast not remembered the days of thy youth, but hast provoked me in all these [things]; behold therefore, I also will recompense thy way upon [thy] head, saith the Lord GOD: and thou shalt not commit this lewdness above all thy abominations.", "vulgate": "eo quod non fueris recordata dierum adulescentiae tuae et provocasti me in omnibus his quapropter et ego vias tuas in capite tuo dedi ait Dominus Deus et non feci iuxta scelera tua in omnibus abominationibus tuis;", "brenton": "Because thou didst not remember thine infancy, and thou didst grieve me in all these things; therefore, behold, I have recompensed thy ways upon thine head, saith the Lord: for thus hast thou wrought ungodliness above all thine other iniquities."}}, {"v": 44, "ref": "16:44", "o": "הִנֵּה֙ כָּל הַ/מֹּשֵׁ֔ל עָלַ֥יִ/ךְ יִמְשֹׁ֖ל לֵ/אמֹ֑ר כְּ/אִמָּ֖/ה בִּתָּֽ/הּ", "en": {"kjv": "Behold, every one that useth proverbs shall use this proverb against thee, saying, As is the mother, so is her daughter.", "web": "Behold, everyone who uses proverbs shall use this proverb against you, saying, As is the mother, so is her daughter.", "bsb": "Behold, all who speak in proverbs will quote this proverb about you: ‘Like mother, like daughter.’", "asv": "Behold, every one that useth proverbs shall use this proverb against thee, saying, As is the mother, so is her daughter.", "ylt": "Lo, every one using a simile, Doth use a simile concerning thee, saying: As the mother--her daughter!", "dra": "Behold every one that useth a common proverb, shall use this against thee, saying: As the mother was, so also is her daughter.", "bbe": "See, in every common saying about you it will be said, As the mother is, so is her daughter.", "geneva": "Beholde, all that vse prouerbes, shall vse this prouerbe against thee, saying, As is the mother, so is her daughter.", "wycliffe": "Lo! ech man that seith a prouerbe comynli, schal take it in thee,", "rotherham": "Lo! every one who useth proverbs, against thee, shall use a proverb saying,— Like the mother, so her daughter!", "darby": "Behold, every one that useth proverbs shall speak in a proverb against thee, saying, As the mother, [so is] her daughter!", "twenty": "", "jps": "Behold, every one that useth proverbs shall use this proverb against thee, saying: As the mother, so her daughter.", "acv": "Behold, everyone who uses proverbs shall use this proverb against thee, saying, As is the mother, so is her daughter.", "anderson": "", "haweis": "", "noyes": "Behold, all they that use proverbs shall utter this proverb concerning thee: \"As the mother, so the daughter.\"", "webster": "Behold, every one that useth proverbs shall use [this] proverb against thee, saying, As [is] the mother, [so is] her daughter.", "vulgate": "ecce omnis qui dicit vulgo proverbium in te adsumet illud dicens sicut mater ita et filia eius;", "brenton": "These are all the things they have spoken against thee in a proverb, saying,"}}, {"v": 45, "ref": "16:45", "o": "בַּת אִמֵּ֣/ךְ אַ֔תְּ גֹּעֶ֥לֶת אִישָׁ֖/הּ וּ/בָנֶ֑י/הָ וַ/אֲח֨וֹת אֲחוֹתֵ֜/ךְ אַ֗תְּ אֲשֶׁ֤ר גָּֽעֲ֨לוּ֙ אַנְשֵׁי/הֶ֣ן וּ/בְנֵי/הֶ֔ן אִמְּ/כֶ֣ן חִתִּ֔ית וַ/אֲבִי/כֶ֖ן אֱמֹרִֽי", "en": {"kjv": "Thou art thy mother’s daughter, that lotheth her husband and her children; and thou art the sister of thy sisters, which lothed their husbands and their children: your mother was an Hittite, and your father an Amorite.", "web": "You are the daughter of your mother, who loathes her husband and her children; and you are the sister of your sisters, who loathed their husbands and their children: your mother was a Hittite, and your father an Amorite.", "bsb": "You are the daughter of your mother, who despised her husband and children. You are the sister of your sisters, who despised their husbands and children. Your mother was a Hittite and your father an Amorite.", "asv": "Thou art the daughter of thy mother, that loatheth her husband and her children; and thou art the sister of thy sisters, who loathed their husbands and their children: your mother was a Hittite, and your father an Amorite.", "ylt": "Thy mother's daughter thou art , Loathing her husband and her sons, And thy sisters' sister thou art , Who loathed their husbands and their sons, Your mother is a Hittite, and your father an Amorite.", "dra": "Thou art thy mother's daughter, that cast off her husband, and her children: and thou art the sister of thy sisters, who cast off their husbands, and their children: your mother was a Cethite, and your father an Amorrhite.", "bbe": "You are the daughter of your mother whose soul is turned in disgust from her husband and her children; and you are the sister of your sisters who were turned in disgust from their husbands and their children: your mother was a Hittite and your father an Amorite.", "geneva": "Thou art thy mothers daughter, that hath cast off her husband and her children, and thou art the sister of thy sisters, which forsooke their husbands and their children: your mother is an Hittite, and your father an Amorite.", "wycliffe": "and schal seie, As the modir, so and the douytir of hir. Thou art the douyter of thi modir, that castide awey hir hosebonde and hir sones; and thou art the sister of thi sistris, that castiden a wei her hosebondis and her sones. Thi modir is Cetei, and thi fadir is Ammorrei;", "rotherham": "The daughter of thy mother, thou art! One abhorring her own husband and her own children,— Yea the sister of thy sisters, thou art Who abhorred their own husbands and their own children, Your mother was a Hittite, And your father an Amorite.", "darby": "Thou art the daughter of thy mother that loathed her husband and her children; and thou art the sister of thy sisters, who loathed their husbands and their children. Your mother was a Hittite, and your father an Amorite.", "twenty": "", "jps": "Thou art thy mother's daughter, that loatheth her husband and her children; and thou art the sister of thy sisters, who loathed their husbands and their children; your mother was a Hittite, and your father an Amorite.", "acv": "Thou are the daughter of thy mother, who loathes her husband and her sons. And thou are the sister of thy sisters, who loathed their husbands and their sons. Your mother was a Hittite, and your father an Amorite.", "anderson": "", "haweis": "", "noyes": "Thou art the daughter of thy mother, that loathed her husband and her children; and thou art the sister of thy sisters, that loathed their husbands and their children; your mother was a Hittite, and your father an Amorite.", "webster": "Thou [art] thy mother's daughter, that lotheth her husband and her children; and thou [art] the sister of thy sisters, who lothed their husbands and their children: your mother [was] a Hittite, and your father an Amorite.", "vulgate": "filia matris tuae es tu quae proiecit virum suum et filios suos et soror sororum tuarum tu quae proiecerunt viros suos et filios suos mater vestra Cetthea et pater vester Amorreus;", "brenton": "As is the mother, so is thy mother's daughter: thou art she that has rejected her husband and her children; and the sisters of thy sisters have rejected their husbands and their children: your mother was a Chettite, and your father an Amorite."}}, {"v": 46, "ref": "16:46", "o": "וַ/אֲחוֹתֵ֨/ךְ הַ/גְּדוֹלָ֤ה שֹֽׁמְרוֹן֙ הִ֣יא וּ/בְנוֹתֶ֔י/הָ הַ/יּוֹשֶׁ֖בֶת עַל שְׂמֹאולֵ֑/ךְ וַ/אֲחוֹתֵ֞/ךְ הַ/קְּטַנָּ֣ה מִמֵּ֗/ךְ הַ/יּוֹשֶׁ֨בֶת֙ מִֽ/ימִינֵ֔/ךְ סְדֹ֖ם וּ/בְנוֹתֶֽי/הָ", "en": {"kjv": "And thine elder sister is Samaria, she and her daughters that dwell at thy left hand: and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters.", "web": "Your elder sister is Samaria, who dwells at your left hand, she and her daughters; and your younger sister, who dwells at your right hand, is Sodom and her daughters.", "bsb": "Your older sister was Samaria, who lived with her daughters to your north; and your younger sister was Sodom, who lived with her daughters to your south.", "asv": "And thine elder sister is Samaria, that dwelleth at thy left hand, she and her daughters; and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters.", "ylt": "And thine elder sister is Samaria, she and her daughters, Who is dwelling at thy left hand, And thy younger sister, who is dwelling on thy right hand, is Sodom and her daughters.", "dra": "And thy elder sister is Samaria, she and her daughters that dwell at thy left hand: and thy younger sister that dwelleth at thy right hand is Sodom, and her daughters.", "bbe": "Your older sister is Samaria, living at your left hand, she and her daughters: and your younger sister, living at your right hand, is Sodom and her daughters.", "geneva": "And thine elder sister is Samaria, and her daughters, that dwell at thy left hand, and thy yong sister, that dwelleth at thy right hand, is Sodom, and her daughters.", "wycliffe": "and thi gretter sister is Samarie, sche and hir douytris, that dwellen at thi left side; but thi sistir lesse than thou, that dwellith at thi riyt side, is Sodom, and hir douytris.", "rotherham": "And thine elder sister, was Samaria, she and her daughters, dwelling on thy left hand,— And thy sister younger than thou dwelling on thy right hand was Sodom and her daughters.", "darby": "And thine elder sister is Samaria that dwelleth at thy left hand, she and her daughters; and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters.", "twenty": "", "jps": "And thine elder sister is Samaria, that dwelleth at thy left hand, she and her daughters; and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters.", "acv": "And thine elder sister is Samaria, who dwells at thy left hand, she and her daughters. And thy younger sister, who dwells at thy right hand, is Sodom and her daughters.", "anderson": "", "haweis": "", "noyes": "And thine elder sister is Samaria, with her daughters, that dwelleth at thy left hand; and thy younger sister, that dwelleth at thy right hand, is Sodom, with her daughters.", "webster": "And thy elder sister [is] Samaria, she and her daughters that dwell at thy left hand: and thy younger sister, that dwelleth at thy right hand, [is] Sodom and her daughters.", "vulgate": "et soror tua maior Samaria ipsa et filiae eius quae habitat ad sinistram tuam soror autem tua minor te quae habitat a dextris tuis Sodoma et filiae eius;", "brenton": "Your elder sister who dwells on thy left hand is Samaria, she and her daughters: and thy younger sister, that dwells on the right hand, is Sodom and her daughters."}}, {"v": 47, "ref": "16:47", "o": "וְ/לֹ֤א בְ/דַרְכֵי/הֶן֙ הָלַ֔כְתְּ וּ/בְ/תוֹעֲבֽוֹתֵי/הֶ֖ן עשיתי עָשִׂ֑ית כִּ/מְעַ֣ט קָ֔ט וַ/תַּשְׁחִ֥תִי מֵ/הֵ֖ן בְּ/כָל דְּרָכָֽיִ/ךְ", "en": {"kjv": "Yet hast thou not walked after their ways, nor done after their abominations: but, as if that were a very little thing, thou wast corrupted more than they in all thy ways.", "web": "Yet you have not walked in their ways, nor done after their abominations; but, soon you were more corrupt than they in all your ways.", "bsb": "And you not only walked in their ways and practiced their abominations, but soon you were more depraved than they were.", "asv": "Yet hast thou not walked in their ways, nor done after their abominations; but, as if that were a very little thing, thou wast more corrupt than they in all thy ways.", "ylt": "And--in their ways thou hast not walked, And according to their abominations done, As a little thing it hath been loathed, And thou dost more corruptly than they in all thy ways.", "dra": "But neither hast thou walked in their ways, nor hast thou done a little less than they according to their wickednesses: thou hast done almost more wicked things than they in all thy ways.", "bbe": "Still you have not gone in their ways or done the disgusting things which they have done; but, as if that was only a little thing, you have gone deeper in evil than they in all your ways.", "geneva": "Yet hast thou not walked after their wayes, nor done after their abominations: but as it had bene a very little thing, thou wast corrupted more then they in all thy wayes.", "wycliffe": "But thou yedist not in the weies of hem, nethir thou didist aftir the grete trespassis of hem; hast thou do almest a litil lesse cursidere dedis than thei, in alle thi weies?", "rotherham": "Yet not in their ways, didst thou walk, nor according to their abominations, didst thou do,— As though that were quite too little, thou didst corrupt thyself beyond them in all thy ways.", "darby": "And thou hast not walked in their ways, nor done according to their abominations; but as though that were a very little, thou hast been more corrupt than they in all thy ways.", "twenty": "", "jps": "Yet hast thou not walked in their ways, nor done after their abominations; but in a very little while thou didst deal more corruptly than they in all thy ways.", "acv": "Yet thou have not walked in their ways, nor done according to their abominations, but, like it was a very little thing, thou were more corrupt than they in all thy ways.", "anderson": "", "haweis": "", "noyes": "Yet thou hast not walked in their ways, nor done according to their abominations: that was disdained by you, as a very little thing; thou hast been more corrupt than they in all thy ways.", "webster": "Yet hast thou not walked after their ways, nor done after their abominations: but as [if that were] a very little [thing], thou wast corrupted more than they in all thy ways.", "vulgate": "sed nec in viis earum ambulasti neque secundum scelera earum fecisti pauxillum minus paene sceleratiora fecisti illis in omnibus viis tuis;", "brenton": "Yet notwithstanding thou hast not walked in their ways, neither hast thou done according to their iniquities within a little, but thou hast exceeded them in all thy ways."}}, {"v": 48, "ref": "16:48", "o": "חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה אִם עָֽשְׂתָה֙ סְדֹ֣ם אֲחוֹתֵ֔/ךְ הִ֖יא וּ/בְנוֹתֶ֑י/הָ כַּ/אֲשֶׁ֣ר עָשִׂ֔ית אַ֖תְּ וּ/בְנוֹתָֽיִ/ךְ", "en": {"kjv": "As I live, saith the Lord God, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters.", "web": "As I live, says the Lord Yahweh, Sodom your sister has not done, she nor her daughters, as you have done, you and your daughters.", "bsb": "As surely as I live, declares the Lord GOD, your sister Sodom and her daughters never did as you and your daughters have done.", "asv": "As I live, saith the Lord Jehovah, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters.", "ylt": "I live--an affirmation of the Lord Jehovah, Sodom thy sister hath not done--she and her daughters--As thou hast done--thou and thy daughters.", "dra": "As I live, saith the Lord God, thy sister Sodom herself, and her daughters, have not done as thou hast done, and thy daughters.", "bbe": "By my life, says the Lord, Sodom your sister never did, she or her daughters, what you and your daughters have done.", "geneva": "As I liue, saith the Lord God, Sodom thy sister hath not done, neither shee nor her daughters, as thou hast done and thy daughters.", "wycliffe": "Y lyue, seith the Lord God, for Sodom, thi sister, did not, sche and hir douytris, as thou didist, and thi douytris.", "rotherham": "As I live, Declareth My Lord Yahweh, Very! Sodom thy sister had not done, neither she nor her daughters,—as thou and thy daughters have done.", "darby": "[As] I live, saith the Lord Jehovah, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters!", "twenty": "", "jps": "As I live, saith the L-rd GOD, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters.", "acv": "As I live, says the lord Jehovah, Sodom thy sister has not done, she nor her daughters, as thou have done, thou and thy daughters.", "anderson": "", "haweis": "", "noyes": "As I live, saith the Lord Jehovah, Sodom, thy sister, hath not done, she nor her daughters, as thou hast done, thou and thy daughters.", "webster": "[As] I live, saith the Lord GOD, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters.", "vulgate": "vivo ego dicit Dominus Deus quia non fecit Sodoma soror tua ipsa et filiae eius sicut fecisti tu et filiae tuae;", "brenton": "As I live, saith the Lord, this Sodom and her daughters have not done as thou and thy daughters have done."}}, {"v": 49, "ref": "16:49", "o": "הִנֵּה זֶ֣ה הָיָ֔ה עֲוֺ֖ן סְדֹ֣ם אֲחוֹתֵ֑/ךְ גָּא֨וֹן שִׂבְעַת לֶ֜חֶם וְ/שַׁלְוַ֣ת הַשְׁקֵ֗ט הָ֤יָה לָ/הּ֙ וְ/לִ/בְנוֹתֶ֔י/הָ וְ/יַד עָנִ֥י וְ/אֶבְי֖וֹן לֹ֥א הֶחֱזִֽיקָה", "en": {"kjv": "Behold, this was the iniquity of thy sister Sodom, pride, fulness of bread, and abundance of idleness was in her and in her daughters, neither did she strengthen the hand of the poor and needy.", "web": "Behold, this was the iniquity of your sister Sodom: pride, fullness of bread, and prosperous ease was in her and in her daughters; neither did she strengthen the hand of the poor and needy.", "bsb": "Now this was the iniquity of your sister Sodom: She and her daughters were arrogant, overfed, and complacent; they did not help the poor and needy.", "asv": "Behold, this was the iniquity of thy sister Sodom: pride, fulness of bread, and prosperous ease was in her and in her daughters; neither did she strengthen the hand of the poor and needy.", "ylt": "Lo, this hath been the iniquity of Sodom thy sister, Arrogancy, fulness of bread, and quiet ease, Have been to her and to her daughters, And the hand of the afflicted and needy She hath not strengthened.", "dra": "Behold this was the iniquity of Sodom thy sister, pride, fulness of bread, and abundance, and the idleness of her, and of her daughters: and they did not put forth their hand to the needy, and the poor.", "bbe": "Truly, this was the sin of your sister Sodom: pride, a full measure of food, and the comforts of wealth in peace, were seen in her and her daughters, and she gave no help to the poor or to those in need.", "geneva": "Beholde, this was the iniquitie of thy sister Sodom, Pride, fulnesse of bread, and aboundance of idlenesse was in her, and in her daughters: neither did shee strengthen the hande of the poore and needie.", "wycliffe": "Lo! this was the wickidnesse of Sodom, thi sister, pride, fulnesse of breed, and habundaunce, and idilnesse of hir, and of hir douytris; and thei puttiden not hond to a nedi man and pore.", "rotherham": "Lo! this became the iniquity of Sodom thy sister,— Pride, fulness of bread, and careless security came to her and to her daughters, And the hand of the oppressed and the needy, she strengthened not.", "darby": "Behold, this was the iniquity of thy sister Sodom: pride, fulness of bread, and careless ease was in her and in her daughters, but she did not strengthen the hand of the poor and needy.", "twenty": "", "jps": "Behold, this was the iniquity of thy sister Sodom: pride, fulness of bread, and careless ease was in her and in her daughters; neither did she strengthen the hand of the poor and needy.", "acv": "Behold, this was the iniquity of thy sister Sodom: pride, fullness of bread, and prosperous ease was in her and in her daughters, and she did not strengthen the hand of a poor and needy man.", "anderson": "", "haweis": "", "noyes": "Behold, this was the iniquity of Sodom, thy sister: in pride, superabundance, and careless ease did she live, she and her daughters, and the hand of the poor and needy she did not strengthen;", "webster": "Behold, this was the iniquity of thy sister Sodom, pride, fullness of bread, and abundance of idleness was in her and in her daughters, neither did she strengthen the hand of the poor and needy.", "vulgate": "ecce haec fuit iniquitas Sodomae sororis tuae superbia saturitas panis et abundantia et otium ipsius et filiarum eius et manum egeno et pauperi non porrigebant;", "brenton": "Moreover this was the sin of thy sister Sodom, pride: she and her daughters lived in pleasure, in fullness of bread and in abundance: this belonged to her and her daughters, and they helped not the hand of the poor and needy."}}, {"v": 50, "ref": "16:50", "o": "וַֽ/תִּגְבְּהֶ֔ינָה וַ/תַּעֲשֶׂ֥ינָה תוֹעֵבָ֖ה לְ/פָנָ֑/י וָ/אָסִ֥יר אֶתְ/הֶ֖ן כַּ/אֲשֶׁ֥ר רָאִֽיתִי", "en": {"kjv": "And they were haughty, and committed abomination before me: therefore I took them away as I saw good.", "web": "They were haughty, and committed abomination before me: therefore I took them away when I saw it.", "bsb": "Thus they were haughty and committed abominations before Me. Therefore I removed them, as you have seen.", "asv": "And they were haughty, and committed abomination before me: therefore I took them away as I saw good.", "ylt": "And they are haughty and do abomination before Me, And I turn them aside when I have seen.", "dra": "And they were lifted up, and committed abominations before me: and I took them away as thou hast seen.", "bbe": "They were full of pride and did what was disgusting to me: and so I took them away as you have seen.", "geneva": "But they were hautie, and committed abomination before mee: therefore I tooke them away, as pleased me.", "wycliffe": "And thei weren enhaunsid, and diden other abhominaciouns bifore me; and Y took hem awei, as thou hast seyn.", "rotherham": "So then they became haughty, and committed abomination before me,- And I took them away. when I saw [it],", "darby": "And they were haughty, and committed abomination before me, and I took them away when I saw [it].", "twenty": "", "jps": "And they were haughty, and committed abomination before Me; therefore I removed them when I saw it.", "acv": "And they were haughty, and committed abomination before me. Therefore I took them away as I saw fit.", "anderson": "", "haweis": "", "noyes": "and they were haughty, and committed abomination before me; therefore I took them away when I saw it.", "webster": "And they were haughty, and committed abomination before me: therefore I took them away as I saw [good].", "vulgate": "et elevatae sunt et fecerunt abominationes coram me et abstuli eas sicut vidisti;", "brenton": "And they boasted, and wrought iniquities before me: so I cut them off as I saw fit."}}, {"v": 51, "ref": "16:51", "o": "וְ/שֹׁ֣מְר֔וֹן כַּ/חֲצִ֥י חַטֹּאתַ֖יִ/ךְ לֹ֣א חָטָ֑אָה וַ/תַּרְבִּ֤י אֶת תּוֹעֲבוֹתַ֨יִ/ךְ֙ מֵ/הֵ֔נָּה וַ/תְּצַדְּקִי֙ אֶת אחות/ך אֲחוֹתַ֔יִ/ךְ בְּ/כָל תּוֹעֲבוֹתַ֖יִ/ךְ אֲשֶׁ֥ר עשיתי עָשִֽׂית", "en": {"kjv": "Neither hath Samaria committed half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters in all thine abominations which thou hast done.", "web": "Neither has Samaria committed half of your sins; but you have multiplied your abominations more than they, and have justified your sisters by all your abominations which you have done.", "bsb": "Furthermore, Samaria did not commit half the sins you did. You have multiplied your abominations beyond theirs, and all the abominations you have committed have made your sisters appear righteous.", "asv": "Neither hath Samaria committed half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters by all thine abominations which thou hast done.", "ylt": "As to Samaria, as the half of thy sins--she hath not sinned, And thou dost multiply thine abominations more than they, And dost justify thy sisters by all thy abominations that thou hast done.", "dra": "And Samaria committed not half thy sins: but thou hast surpassed them with thy crimes, and hast justified thy sisters by all thy abominations which thou hast done.", "bbe": "And Samaria has not done half your sins; but you have made the number of your disgusting acts greater than theirs, making your sisters seem more upright than you by all the disgusting things which you have done.", "geneva": "Neither hath Samaria committed halfe of thy sinnes, but thou hast exceeded them in thine abominations, and hast iustified thy sisters in all thine abominations, which thou hast done.", "wycliffe": "And Samarie synnede not the half of thi synnes, but thou hast ouercome hem in thi grete trespassis; and thou hast iustified thi sistris in alle thin abhomynaciouns, whiche thou wrouytist.", "rotherham": "Nor did, Samaria, commit, one-half thy sins,— But thou didst multiply thine abominations more than they, And didst cause thy sisters to appear righteous, by all the abominations which thou didst commit.", "darby": "And Samaria hath not sinned according to the half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters by all thine abominations which thou hast done.", "twenty": "", "jps": "Neither hath Samaria committed even half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters by all thine abominations which thou hast done.", "acv": "Neither has Samaria committed half of thy sins, but thou have multiplied thine abominations more than they, and have justified thy sisters by all thine abominations which thou have done.", "anderson": "", "haweis": "", "noyes": "Neither hath Samaria committed half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters in all thine abominations which thou hast done.", "webster": "Neither hath Samaria committed half of thy sins; but thou hast multiplied thy abominations more than they, and hast justified thy sisters in all thy abominations which thou hast done.", "vulgate": "et Samaria dimidium peccatorum tuorum non peccavit sed vicisti eas sceleribus tuis et iustificasti sorores tuas in omnibus abominationibus tuis quas operata es;", "brenton": "Also Samaria has not sinned according to half of thy sins; but thou hast multiplied thine iniquities beyond them, and thou hast justified thy sisters in all thine iniquities which thou hast committed."}}, {"v": 52, "ref": "16:52", "o": "גַּם אַ֣תְּ שְׂאִ֣י כְלִמָּתֵ֗/ךְ אֲשֶׁ֤ר פִּלַּלְתְּ֙ לַֽ/אֲחוֹתֵ֔/ךְ בְּ/חַטֹּאתַ֛יִ/ךְ אֲשֶׁר הִתְעַ֥בְתְּ מֵ/הֵ֖ן תִּצְדַּ֣קְנָה מִמֵּ֑/ךְ וְ/גַם אַ֥תְּ בּ֨וֹשִׁי֙ וּ/שְׂאִ֣י כְלִמָּתֵ֔/ךְ בְּ/צַדֶּקְתֵּ֖/ךְ אַחְיוֹתֵֽ/ךְ", "en": {"kjv": "Thou also, which hast judged thy sisters, bear thine own shame for thy sins that thou hast committed more abominable than they: they are more righteous than thou: yea, be thou confounded also, and bear thy shame, in that thou hast justified thy sisters.", "web": "You also, bear you your own shame, in that you have given judgment for your sisters; through your sins that you have committed more abominable than they, they are more righteous that you: yes, be also confounded, and bear your shame, in that you have justified your sisters.", "bsb": "So now you must bear your disgrace, since you have brought justification for your sisters. For they appear more righteous than you, because your sins were more vile than theirs. So you too must bear your shame and disgrace, since you have made your sisters appear righteous.", "asv": "Thou also, bear thou thine own shame, in that thou hast given judgment for thy sisters; through thy sins that thou hast committed more abominable than they, they are more righteous than thou: yea, be thou also confounded, and bear thy shame, in that thou hast justified thy sisters.", "ylt": "Thou also--bear thy shame, That thou hast adjudged to thy sisters, Because of thy sins that thou hast done more abominably than they, They are more righteous than thou, And thou, also, be ashamed and bear thy shame, In thy justifying thy sisters.", "dra": "Therefore do thou also bear thy confusion, thou that hast surpassed thy sisters with thy sins, doing more wickedly than they: for they are justified above thee, therefore be thou also confounded, and bear thy shame, thou that hast justified thy sisters.", "bbe": "And you yourself will be put to shame, in that you have given the decision for your sisters; through your sins, which are more disgusting than theirs, they are more upright than you: truly, you will be shamed and made low, for you have made your sisters seem upright.", "geneva": "Therefore thou which hast iustified thy sisters, beare thine owne shame for thy sinnes, that thou hast committed more abominable then they which are more righteous then thou art: be thou therefore confounded also, and beare thy shame, seeing that thou hast iustified thy sisters.", "wycliffe": "Therfor and thou bere thi schenschipe, that hast ouercome thi sistris with thi synnes, and didist more cursidli than thei; for thei ben iustified of thee. Therfor and be thou schent, and bere thi schenschipe, which hast iustified thi sistris.", "rotherham": "Thou also bear thine own reproach, which thou didst adjudge to thy sisters, by thy sins in which thou wast more abominable than they, thou didst make them appear more righteous than thou,— Thou also, therefore turn thou pale and bear thine own reproach, for making thy sisters appear righteous!", "darby": "Thou also, who hast judged thy sisters, bear thine own confusion, because of thy sins in which thou hast acted more abominably than they: they are more righteous than thou. So be thou ashamed also, and bear thy confusion, in that thou hast justified thy sisters.", "twenty": "", "jps": "Thou also, bear thine own shame, in that thou hast given judgment for thy sisters; through thy sins that thou hast committed more abominable than they, they are more righteous than thou; yea, be thou also confounded, and bear thy shame, in that thou hast justified thy sisters.", "acv": "Thou also, bear thou thine own shame, in that thou have given judgment for thy sisters, through thy sins that thou have committed more abominable than they. They are more righteous than thou. Yea, be thou also confounded, and bear thy shame, in that thou have justified thy sisters.", "anderson": "", "haweis": "", "noyes": "Now, therefore, bear thou thy shame, to which thou hast condemned thy sisters, since by thy sins which thou hast committed, more abominable than they, they are more righteous than thou. Yea, be thou confounded and bear thy shame, in that thou hast justified thy sisters.", "webster": "Thou also, who hast judged thy sisters, bear thy own shame for thy sins that thou hast committed more abominable than they: they are more righteous than thou: yes, be thou confounded also, and bear thy shame, in that thou hast justified thy sisters.", "vulgate": "ergo et tu porta confusionem tuam quae vicisti sorores tuas peccatis tuis sceleratius agens ab eis iustificatae sunt enim a te ergo et tu confundere et porta ignominiam tuam quae iustificasti sorores tuas;", "brenton": "Thou therefore bear thy punishment, for that thou hast corrupted thy sisters by thy sins which thou hast committed beyond them; and thou hast made them appear more righteous than thyself: thou therefore be ashamed, and bear thy dishonour, in that thou hast justified thy sisters."}}, {"v": 53, "ref": "16:53", "o": "וְ/שַׁבְתִּי֙ אֶת שְׁבִ֣יתְ/הֶ֔ן אֶת שבית שְׁב֤וּת סְדֹם֙ וּ/בְנוֹתֶ֔י/הָ וְ/אֶת שבית שְׁב֥וּת שֹׁמְר֖וֹן וּ/בְנוֹתֶ֑י/הָ ו/שבית וּ/שְׁב֥וּת שְׁבִיתַ֖יִ/ךְ בְּ/תוֹכָֽ/הְנָה", "en": {"kjv": "When I shall bring again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, then will I bring again the captivity of thy captives in the midst of them:", "web": "I will turn again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, and the captivity of your captives in their midst;", "bsb": "But I will restore Sodom and her daughters from captivity, as well as Samaria and her daughters. And I will restore you along with them.", "asv": "And I will turn again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, and the captivity of thy captives in the midst of them;", "ylt": "And I have turned back to their captivity, The captivity of Sodom and her daughters, And the captivity of Samaria and her daughters, And the captivity of thy captives in their midst,", "dra": "And I will bring back and restore them by bringing back Sodom, with her daughters, and by bringing back Samaria, and her daughters: and I will bring those that return of thee in the midst of them.", "bbe": "And I will let their fate be changed, the fate of Sodom and her daughters, and the fate of Samaria and her daughters, and your fate with theirs.", "geneva": "Therefore I will bring againe their captiuitie with the captiuitie of Sodom, and her daughters, and with the captiuitie of Samaria, and her daughters: euen the captiuitie of thy captiues in the middes of them,", "wycliffe": "And Y schal conuerte and restore hem by the conuersioun of Sodom with hir douytris, and bi the conuersioun of Samarie and of hir douytris; and Y schal conuerte thi turnyng ayen in the myddis of hem,", "rotherham": "When therefore I bring back their captivity, The captivity of Sodom and her daughters, And the captivity of Samaria and her daughters Then will I bring back thy captivities in their midst:", "darby": "And I will bring again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, and the captivity of thy captives in the midst of them;", "twenty": "", "jps": "And I will turn their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, and the captivity of thy captives in the midst of them;", "acv": "And I will turn back again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, and the captivity of thy captives in the midst of them,", "anderson": "", "haweis": "", "noyes": "Yet I will bring them back from their captivity, even Sodom and her daughters from their captivity, and Samaria and her daughters from their captivity; thee also will I bring back from thy captivity in the midst of them;", "webster": "When I shall bring again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, then [will I bring again] the captivity of thy captives in the midst of them:", "vulgate": "et convertam restituens eas conversione Sodomorum cum filiabus suis et conversione Samariae et filiarum eius et convertam reversionem tuam in medio earum;", "brenton": "And I will turn their captivity, even the captivity of Sodom and her daughters; and I will turn the captivity of Samaria and her daughters; and I will turn thy captivity in the midst of them:"}}, {"v": 54, "ref": "16:54", "o": "לְמַ֨עַן֙ תִּשְׂאִ֣י כְלִמָּתֵ֔/ךְ וְ/נִכְלַ֕מְתְּ מִ/כֹּ֖ל אֲשֶׁ֣ר עָשִׂ֑ית בְּ/נַחֲמֵ֖/ךְ אֹתָֽ/ן", "en": {"kjv": "That thou mayest bear thine own shame, and mayest be confounded in all that thou hast done, in that thou art a comfort unto them.", "web": "that you may bear your own shame, and may be ashamed because of all that you have done, in that you are a comfort to them.", "bsb": "So you will bear your disgrace and be ashamed of all you did to comfort them.", "asv": "that thou mayest bear thine own shame, and mayest be ashamed because of all that thou hast done, in that thou art a comfort unto them.", "ylt": "So that thou dost bear thy shame, And hast been ashamed of all that thou hast done, In thy comforting them.", "dra": "That thou mayest bear thy shame, and mayest be confounded in all that thou hast done, comforting them.", "bbe": "So that you will be shamed and made low because of all you have done, when I have mercy on you.", "geneva": "That thou mayest beare thine owne shame, and mayest bee confounded in all that thou hast done, in that thou hast comforted them.", "wycliffe": "that thou bere thi schenschipe, and be aschamed in alle thingis whiche thou didist, coumfortynge hem.", "rotherham": "That thou mayest bear thine own reproach, And take to thyself reproach because of all that thou didst in comforting them.", "darby": "that thou mayest bear thy confusion, and mayest be confounded for all that thou hast done, in that thou comfortest them.", "twenty": "", "jps": "that thou mayest bear thine own shame, and mayest be ashamed because of all that thou hast done, in that thou art a comfort unto them.", "acv": "that thou may bear thine own shame, and may be ashamed because of all that thou have done, in that thou are a comfort to them.", "anderson": "", "haweis": "", "noyes": "that thou mayst bear thy shame, and mayst be confounded on account of all which thou hast done, in that thou art a comfort to them.", "webster": "That thou mayest bear thy own shame, and mayest be confounded in all that thou hast done, in that thou art a comfort to them.", "vulgate": "ut portes ignominiam tuam et confundaris in omnibus quae fecisti consolans eas;", "brenton": "that thou mayest bear thy punishment, and be dishonoured for all that thou hast done in provoking me to anger."}}, {"v": 55, "ref": "16:55", "o": "וַ/אֲחוֹתַ֗יִ/ךְ סְדֹ֤ם וּ/בְנוֹתֶ֨י/הָ֙ תָּשֹׁ֣בְןָ לְ/קַדְמָתָ֔/ן וְ/שֹֽׁמְרוֹן֙ וּ/בְנוֹתֶ֔י/הָ תָּשֹׁ֖בְןָ לְ/קַדְמָתָ֑/ן וְ/אַתְּ֙ וּ/בְנוֹתַ֔יִ/ךְ תְּשֻׁבֶ֖ינָה לְ/קַדְמַתְ/כֶֽן", "en": {"kjv": "When thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate, then thou and thy daughters shall return to your former estate.", "web": "Your sisters, Sodom and her daughters, shall return to their former estate; and Samaria and her daughters shall return to their former estate; and you and your daughters shall return to your former estate.", "bsb": "And your sisters, Sodom with her daughters and Samaria with her daughters, will return to their former state. You and your daughters will also return to your former state.", "asv": "And thy sisters, Sodom and her daughters, shall return to their former estate; and Samaria and her daughters shall return to their former estate; and thou and thy daughters shall return to your former estate.", "ylt": "And thy sisters, Sodom and her daughters, Do turn back to their former state, And Samaria and her daughters Do turn back to their former state, And thou and thy daughters do turn back to your former state.", "dra": "And thy sister Sodom and her daughters shall return to their ancient state: and Samaria and her daughters shall return to their ancient state: and thou and thy daughters shall return to your ancient state.", "bbe": "And your sisters, Sodom and her daughters, will go back to their first condition, and Samaria and her daughters will go back to their first condition, and you and your daughters will go back to your first condition.", "geneva": "And thy sister Sodom and her daughters shall returne to their former state: Samaria also and her daughters shall returne to their former state, when thou and thy daughters shall returne to your former state.", "wycliffe": "And thi sister Sodom and hir doytris schulen turne ayen to her eldnesse; and Samarie and hir douytris shulen turne ayen to her eeldnesse; and thou and thi douytris turne ayen to youre eldnesse.", "rotherham": "When thy sisters Sodom and her daughters shall return to their former estate, And Samaria and her daughters shall return to their former estate Then thou and thy daughters, shall return to your former estate.", "darby": "And thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate; thou also and thy daughters, ye shall return to your former estate.", "twenty": "", "jps": "And thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate, and thou and thy daughters shall return to your former estate.", "acv": "And thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate, and thou and thy daughters shall return to your former estate.", "anderson": "", "haweis": "", "noyes": "And thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate, and thou and thy daughters shall return to your former estate.", "webster": "When thy sisters, Sodom and her daughters, shall return to their former state, and Samaria and her daughters shall return to their former state, then thou and thy daughters shall return to your former state.", "vulgate": "et soror tua Sodoma et filiae eius revertentur ad antiquitatem suam et Samaria et filiae eius revertentur ad antiquitatem suam et tu et filiae tuae revertimini ad antiquitatem vestram;", "brenton": "And thy sister Sodom and her daughters shall be restored as they were at the beginning, and thou and thy daughters shall be restored as ye were at the beginning."}}, {"v": 56, "ref": "16:56", "o": "וְ/ל֤וֹא הָֽיְתָה֙ סְדֹ֣ם אֲחוֹתֵ֔/ךְ לִ/שְׁמוּעָ֖ה בְּ/פִ֑י/ךְ בְּ/י֖וֹם גְּאוֹנָֽיִ/ךְ", "en": {"kjv": "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,", "web": "For your sister Sodom was not mentioned by your mouth in the day of your pride,", "bsb": "Did you not treat your sister Sodom as an object of scorn in the day of your pride,", "asv": "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,", "ylt": "And thy sister Sodom hath not been for a report in thy mouth, In the day of thine arrogancy,", "dra": "And Sodom thy sister was not heard of in thy mouth, in the day of thy pride,", "bbe": "Was not your sister Sodom an oath in your mouth in the day of your pride,", "geneva": "For thy sister Sodom was not heard of by thy report in the day of thy pride,", "wycliffe": "Forsothe Sodom, thi sister, was not herd in thi mouth, in the dai of thi pride,", "rotherham": "And Sodom thy sister was never heard in thy mouth, —In the day of thy pride:", "darby": "Yea, Sodom thy sister was not mentioned by thy mouth in the day of thy pride,", "twenty": "", "jps": "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride;", "acv": "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,", "anderson": "", "haweis": "", "noyes": "And yet Sodom, thy sister, was not mentioned by thy mouth in the day of thy pride", "webster": "For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,", "vulgate": "non fuit autem Sodoma soror tua audita in ore tuo in die superbiae tuae;", "brenton": "And surely thy sister Sodom was not mentioned by thy mouth in the days of thy pride:"}}, {"v": 57, "ref": "16:57", "o": "בְּ/טֶרֶם֮ תִּגָּלֶ֣ה רָעָתֵ/ךְ֒ כְּמ֗וֹ עֵ֚ת חֶרְפַּ֣ת בְּנוֹת אֲרָ֔ם וְ/כָל סְבִיבוֹתֶ֖י/הָ בְּנ֣וֹת פְּלִשְׁתִּ֑ים הַ/שָּׁאט֥וֹת אוֹתָ֖/ךְ מִ/סָּבִֽיב", "en": {"kjv": "Before thy wickedness was discovered, as at the time of thy reproach of the daughters of Syria, and all that are round about her, the daughters of the Philistines, which despise thee round about.", "web": "before your wickedness was uncovered, as at the time of the reproach of the daughters of Syria, and of all who are around her, the daughters of the Philistines, who do despite to you all around.", "bsb": "before your wickedness was uncovered? Even so, you are now scorned by the daughters of Edom and all those around her, and by the daughters of the Philistines—all those around you who despise you.", "asv": "before thy wickedness was uncovered, as at the time of the reproach of the daughters of Syria, and of all that are round about her, the daughters of the Philistines, that do despite unto thee round about.", "ylt": "Before thy wickedness is revealed, As at the time of the reproach of the daughters of Aram, And of all her neighbours, the daughters of the Philistines, Who are despising thee round about.", "dra": "Before thy malice was laid open: as it is at this time, making thee a reproach of the daughters of Syria, and of all the daughters of Palestine round about thee, that encompass thee on all sides.", "bbe": "Before your shame was uncovered? Now you have become like her a word of shame to the daughters of Edom and all who are round about you, the daughters of the Philistines who put shame on you round about.", "geneva": "Before thy wickednes was discouered, as in that same time of the reproch of the daughters of Aram, and of all the daughters of the Philistims round about her which despise thee on all sides.", "wycliffe": "bifore that thi malice was schewid, as in this tyme, in to schenschipe of the douytris of Sirie, and of alle douytris in thi cumpas, of the douytris of Palestyn that ben aboute thee bi cumpas.", "rotherham": "Before thy wickedness was discovered, As now, [thou art] the reproach of the daughters of Syria and all round about her the daughters of the Philistines, —who are despising thee on every side.", "darby": "before thy wickedness was discovered, as at the time of the reproach of the daughters of Syria, and of all that are round about her, the daughters of the Philistines, who despise thee on every side.", "twenty": "", "jps": "before thy wickedness was uncovered, as at the time of the taunt of the daughters of Aram, and of all that are round about her, the daughters of the Philistines, that have thee in disdain round about.", "acv": "before thy wickedness was uncovered, as at the time of the reproach of the daughters of Syria, and of all who are round about her, the daughters of the Philistines, who do despite to thee round about.", "anderson": "", "haweis": "", "noyes": "before thy wickedness was discovered, as in the time of thy reproach from the daughters of Syria, and from all that were round about her, and from the daughters of the Philistines, who despised thee round about.", "webster": "Before thy wickedness was disclosed, as at the time of [thy] reproach of the daughters of Syria, and all [that are] around her, the daughters of the Philistines, who despise thee on every side.", "vulgate": "antequam revelaretur malitia tua sicut hoc tempore in obprobrium filiarum Syriae et cunctarum in circuitu tuo filiarum Palestinarum quae ambiunt te per gyrum;", "brenton": "before thy wickedness was discovered, even now thou art the reproach of the daughters of Syria, and of all that are round about her, even of the daughters of the Philistines that compass thee round about."}}, {"v": 58, "ref": "16:58", "o": "אֶת זִמָּתֵ֥/ךְ וְ/אֶת תּוֹעֲבוֹתַ֖יִ/ךְ אַ֣תְּ נְשָׂאתִ֑י/ם נְאֻ֖ם יְהוָֽה", "en": {"kjv": "Thou hast borne thy lewdness and thine abominations, saith the Lord.", "web": "You have borne your lewdness and your abominations, says Yahweh.", "bsb": "You will bear the consequences of your lewdness and your abominations, declares the LORD.", "asv": "Thou hast borne thy lewdness and thine abominations, saith Jehovah.", "ylt": "Thy devices and thine abominations, Thou hast borne them, an affirmation of Jehovah.", "dra": "Thou hast borne thy wickedness, and thy disgrace, saith the Lord God.", "bbe": "The reward of your evil designs and your disgusting ways has come on you, says the Lord.", "geneva": "Thou hast borne therefore thy wickednesse and thine abomination, saith the Lord.", "wycliffe": "Thou hast bore thi greet trespas, and thi schenschipe, seith the Lord God.", "rotherham": "As for thy crime and thine abominations, thou thyself, dost bear them,— Declareth Yahweh.", "darby": "Thy lewdness and thine abominations, thou bearest them, saith Jehovah.", "twenty": "", "jps": "Thou hast borne thy lewdness and thine abominations, saith HaShem.", "acv": "Thou have borne thy lewdness and thine abominations, says Jehovah.", "anderson": "", "haweis": "", "noyes": "Thy wickedness and thine abominations must thou now bear, saith the Lord Jehovah.", "webster": "Thou hast borne thy lewdness and thy abominations, saith the LORD.", "vulgate": "scelus tuum et ignominiam tuam tu portasti ait Dominus Deus;", "brenton": "As for thine ungodliness and thine iniquities, thou hast borne them, saith the Lord."}}, {"v": 59, "ref": "16:59", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה ו/עשית וְ/עָשִׂ֥יתִי אוֹתָ֖/ךְ כַּ/אֲשֶׁ֣ר עָשִׂ֑ית אֲשֶׁר בָּזִ֥ית אָלָ֖ה לְ/הָפֵ֥ר בְּרִֽית", "en": {"kjv": "For thus saith the Lord God; I will even deal with thee as thou hast done, which hast despised the oath in breaking the covenant.", "web": "For thus says the Lord Yahweh: I will also deal with you as you have done, who have despised the oath in breaking the covenant.", "bsb": "For this is what the Lord GOD says: I will deal with you according to your deeds, since you have despised the oath by breaking the covenant.", "asv": "For thus saith the Lord Jehovah: I will also deal with thee as thou hast done, who hast despised the oath in breaking the covenant.", "ylt": "For thus said the Lord Jehovah: I have dealt with thee as thou hast done, In that thou hast despised an oath--to break covenant.", "dra": "For thus saith the Lord God: I will deal with thee, as thou hast despised the oath, in breaking the covenant:", "bbe": "For this is what the Lord has said: I will do to you as you have done, you who, putting the oath on one side, have let the agreement be broken.", "geneva": "For thus saith the Lord God, I might euen deale with thee, as thou hast done: when thou didest despise the othe, in breaking the couenant.", "wycliffe": "For the Lord God seith these thingis, And Y schal do to thee as thou dispisidist the ooth, that thou schuldist make voide the couenaunt;", "rotherham": "For Thus, saith My Lord, Yahweh, Therefore will I deal with thee just as thou hast dealt,- In that thou didst despise an oath by breaking a covenant.", "darby": "For thus saith the Lord Jehovah: I will even deal with thee as thou hast done, who hast despised the oath, and broken the covenant.", "twenty": "", "jps": "For thus saith the L-rd GOD: I will even deal with thee as thou hast done, who hast despised the oath in breaking the covenant.", "acv": "For thus says the lord Jehovah: I will also deal with thee as thou have done, who have despised the oath in breaking the covenant.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: I will do to thee as thou hast done, who hast despised the oath and hast broken the covenant.", "webster": "For thus saith the Lord GOD; I will even deal with thee as thou hast done, who hast despised the oath in breaking the covenant.", "vulgate": "quia haec dicit Dominus Deus et faciam tibi sicut dispexisti iuramentum ut irritum faceres pactum;", "brenton": "Thus saith the Lord; I will even do to thee as thou hast done, as thou hast dealt shamefully in these things to transgress my covenant."}}, {"v": 60, "ref": "16:60", "o": "וְ/זָכַרְתִּ֨י אֲנִ֧י אֶת בְּרִיתִ֛/י אוֹתָ֖/ךְ בִּ/ימֵ֣י נְעוּרָ֑יִ/ךְ וַ/הֲקִמוֹתִ֥י לָ֖/ךְ בְּרִ֥ית עוֹלָֽם", "en": {"kjv": "Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish unto thee an everlasting covenant.", "web": "Nevertheless I will remember my covenant with you in the days of your youth, and I will establish to you an everlasting covenant.", "bsb": "But I will remember the covenant I made with you in the days of your youth, and I will establish an everlasting covenant with you.", "asv": "Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish unto thee an everlasting covenant.", "ylt": "And I--I have remembered My covenant with thee, In the days of thy youth, And I have established for thee a covenant age-during.", "dra": "And I will remember my covenant with thee in the days of thy youth: and I will establish with thee an everlasting covenant.", "bbe": "But still I will keep in mind the agreement made with you in the days when you were young, and I will make with you an eternal agreement.", "geneva": "Neuerthelesse, I wil remember my couenant made with thee in ye dayes of thy youth, and I wil confirme vnto thee an euerlasting couenant.", "wycliffe": "and Y schal haue mynde on my couenaunt with thee in the daies of thi yongthe, and Y schal reise to thee a couenaunt euerlastynge.", "rotherham": "Therefore will I remember my covenant with thee in the days of thy youth,— And will establish for thee a covenant age-abiding.", "darby": "Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish unto thee an everlasting covenant.", "twenty": "", "jps": "Nevertheless I will remember My covenant with thee in the days of thy youth, and I will establish unto thee an everlasting covenant.", "acv": "Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish to thee an everlasting covenant.", "anderson": "", "haweis": "", "noyes": "But I will remember my covenant with thee in the days of thy youth, and I will establish with thee an everlasting covenant.", "webster": "Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish to thee an everlasting covenant.", "vulgate": "et recordabor ego pacti mei tecum in diebus adulescentiae tuae et suscitabo tibi pactum sempiternum;", "brenton": "And I will remember my covenant made with thee in the days of thine infancy, and I will establish to thee an everlasting covenant."}}, {"v": 61, "ref": "16:61", "o": "וְ/זָכַ֣רְתְּ אֶת דְּרָכַיִ/ךְ֮ וְ/נִכְלַמְתְּ֒ בְּ/קַחְתֵּ֗/ךְ אֶת אֲחוֹתַ֨יִ/ךְ֙ הַ/גְּדֹל֣וֹת מִמֵּ֔/ךְ אֶל הַ/קְּטַנּ֖וֹת מִמֵּ֑/ךְ וְ/נָתַתִּ֨י אֶתְ/הֶ֥ן לָ֛/ךְ לְ/בָנ֖וֹת וְ/לֹ֥א מִ/בְּרִיתֵֽ/ךְ", "en": {"kjv": "Then thou shalt remember thy ways, and be ashamed, when thou shalt receive thy sisters, thine elder and thy younger: and I will give them unto thee for daughters, but not by thy covenant.", "web": "Then you shall remember your ways, and be ashamed, when you shall receive your sisters, your elder sisters and your younger; and I will give them to you for daughters, but not by your covenant.", "bsb": "Then you will remember your ways and be ashamed when you receive your older and younger sisters. I will give them to you as daughters, but not because of My covenant with you.", "asv": "Then shalt thou remember thy ways, and be ashamed, when thou shalt receive thy sisters, thine elder sisters and thy younger; and I will give them unto thee for daughters, but not by thy covenant.", "ylt": "And thou hast remembered thy ways, And thou hast been ashamed, In thy receiving thy sisters--Thine elder with thy younger, And I have given them to thee for daughters, And not by thy covenant.", "dra": "And thou shalt remember thy ways, and be ashamed: when thou shalt receive thy sisters, thy elder and thy younger: and I will give them to thee for daughters, but not by thy covenant.", "bbe": "Then at the memory of your ways you will be overcome with shame, when I take your sisters, the older and the younger, and give them to you for daughters, but not by your agreement.", "geneva": "Then thou shalt remember thy wayes, and be ashamed, when thou shalt receiue thy sisters, both thy elder and thy yonger, and I will giue them vnto thee for daughters, but not by thy couenat.", "wycliffe": "And thou schalt haue mynde on thi weies, and schalt be aschamed, whanne thou schalt resseyue thi sistris grettere than thou, with thi lesse sistris; and Y schal yyue hem in to douytris to thee, but not of thi couenaunt.", "rotherham": "Thou shalt therefore remember thy ways and take to thyself reproach, by receiving thy sisters. The older than thou, And the younger than thou,- And I will give them unto thee for daughters Though not by thine own covenant.", "darby": "And thou shalt remember thy ways, and be confounded, when thou shalt receive thy sisters who are older than thou, together with those who are younger than thou; for I will give them unto thee for daughters, but not by virtue of thy covenant.", "twenty": "", "jps": "Then shalt thou remember thy ways, and be ashamed, when thou shalt receive thy sisters, thine elder sisters and thy younger; and I will give them unto thee for daughters, but not because of thy covenant.", "acv": "Then thou shall remember thy ways, and be ashamed, when thou shall receive thy sisters, thine elder sisters and thy younger, and I will give them to thee for daughters, but not by thy covenant.", "anderson": "", "haweis": "", "noyes": "Then shalt thou remember thy ways, and be ashamed, when thou shalt receive thy sisters, thine elder and thy younger, and I shall give them to thee for daughters, but not by thy observance of thy covenant.", "webster": "Then thou shalt remember thy ways, and be ashamed, when thou shalt receive thy sisters, thy elder and thy younger: and I will give them to thee for daughters, but not by thy covenant.", "vulgate": "et recordaberis viarum tuarum et confunderis cum receperis sorores tuas te maiores cum minoribus tuis et dabo eas tibi in filias sed non ex pacto tuo;", "brenton": "Then thou shalt remember thy way, and shalt be utterly dishonoured when thou receivest thine elder sisters with thy younger ones: and I will give them to thee for building up, but not by thy covenant."}}, {"v": 62, "ref": "16:62", "o": "וַ/הֲקִימוֹתִ֥י אֲנִ֛י אֶת בְּרִיתִ֖/י אִתָּ֑/ךְ וְ/יָדַ֖עַתְּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will establish my covenant with thee; and thou shalt know that I am the Lord:", "web": "I will establish my covenant with you; and you shall know that I am Yahweh;", "bsb": "So I will establish My covenant with you, and you will know that I am the LORD,", "asv": "And I will establish my covenant with thee; and thou shalt know that I am Jehovah;", "ylt": "And I--I have established My covenant with thee, And thou hast known that I am Jehovah.", "dra": "And I will establish my covenant with thee: and thou shalt know that I am the Lord,", "bbe": "And I will make my agreement with you; and you will be certain that I am the Lord:", "geneva": "And I wil establish my couenant with thee, and thou shalt knowe that I am the Lord,", "wycliffe": "And Y schal reise my couenaunt with thee, and thou schalt wite, that Y am the Lord, that thou haue mynde, and be aschamed;", "rotherham": "But I myself, will establish my covenant with thee— And thou shalt know that I, am Yahweh:", "darby": "And I will establish my covenant with thee, and thou shalt know that I [am] Jehovah;", "twenty": "", "jps": "And I will establish My covenant with thee, and thou shalt know that I am HaShem;", "acv": "And I will establish my covenant with thee, and thou shall know that I am Jehovah,", "anderson": "", "haweis": "", "noyes": "But I will establish my covenant with thee, and thou shalt know that I am Jehovah;", "webster": "And I will establish my covenant with thee; and thou shalt know that I [am] the LORD:", "vulgate": "et suscitabo ego pactum meum tecum et scies quia ego Dominus;", "brenton": "And I will establish my covenant with thee; and thou shalt know that I am the Lord:"}}, {"v": 63, "ref": "16:63", "o": "לְמַ֤עַן תִּזְכְּרִי֙ וָ/בֹ֔שְׁתְּ וְ/לֹ֨א יִֽהְיֶה לָּ֥/ךְ עוֹד֙ פִּתְח֣וֹן פֶּ֔ה מִ/פְּנֵ֖י כְּלִמָּתֵ֑/ךְ בְּ/כַפְּרִ/י לָ/ךְ֙ לְ/כָל אֲשֶׁ֣ר עָשִׂ֔ית נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "That thou mayest remember, and be confounded, and never open thy mouth any more because of thy shame, when I am pacified toward thee for all that thou hast done, saith the Lord God.", "web": "that you may remember, and be confounded, and never open your mouth any more, because of your shame, when I have forgiven you all that you have done, says the Lord Yahweh.", "bsb": "so that when I make atonement for all you have done, you will remember and be ashamed and never again open your mouth because of your disgrace, declares the Lord GOD.”", "asv": "that thou mayest remember, and be confounded, and never open thy mouth any more, because of thy shame, when I have forgiven thee all that thou hast done, saith the Lord Jehovah.", "ylt": "So that thou dost remember, And thou hast been ashamed, And there is not to thee any more an opening of the mouth because of thy shame, In My receiving atonement for thee, For all that thou hast done, An affirmation of the Lord Jehovah!'", "dra": "That thou mayest remember, and be confounded, and mayest no more open thy mouth because of thy confusion, when I shall be pacified toward thee for all that thou hast done, saith the Lord God.", "bbe": "So that, at the memory of these things, you may be at a loss, never opening your mouth because of your shame; when you have my forgiveness for all you have done, says the Lord.", "geneva": "That thou mayest remember, and be ashamed, and neuer open thy mouth any more: because of thy shame when I am pacified toward thee, for all that thou hast done, saith the Lord God.", "wycliffe": "and that it be no more to thee to opene the mouth for thi schame, whanne Y schal be plesid to thee in alle thingis whiche thou didist, seith the Lord God.", "rotherham": "To the end thou mayest remember and turn pale, and there be to thee no more, an opening of mouth, because of thy reproach,- In that I have accepted a propitiatory covering for thee as to all that thou hast done, Declareth My Lord. Yahweh.", "darby": "that thou mayest remember, and be ashamed, and no more open thy mouth because of thy confusion, when I forgive thee all that thou hast done, saith the Lord Jehovah.", "twenty": "", "jps": "that thou mayest remember, and be confounded, and never open thy mouth any more, because of thy shame; when I have forgiven thee all that thou hast done, saith the L-rd GOD.'", "acv": "that thou may remember, and be confounded, and never open thy mouth any more, because of thy shame, when I have forgiven thee all that thou have done, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "that thou mayst remember and be confounded, and not open thy mouth any more for shame, when I forgive thee all which thou hast done, saith the Lord Jehovah.", "webster": "That thou mayest remember, and be confounded, and never open thy mouth any more because of thy shame, when I am pacified towards thee for all that thou hast done, saith the Lord GOD.", "vulgate": "ut recorderis et confundaris et non sit tibi ultra aperire os prae confusione tua cum placatus fuero tibi in omnibus quae fecisti ait Dominus Deus;", "brenton": "that thou mayest remember, and be ashamed, and mayest no more be able to open thy mouth for thy shame, when I am reconciled to thee for all that thou hast done, saith the Lord."}}]}, {"c": 17, "verses": [{"v": 1, "ref": "17:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Now the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto mee, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "17:2", "o": "בֶּן אָדָ֕ם ח֥וּד חִידָ֖ה וּ/מְשֹׁ֣ל מָשָׁ֑ל אֶל בֵּ֖ית יִשְׂרָאֵֽל", "en": {"kjv": "Son of man, put forth a riddle, and speak a parable unto the house of Israel;", "web": "Son of man, tell a riddle, and speak a parable to the house of Israel;", "bsb": "“Son of man, pose a riddle; speak a parable to the house of Israel", "asv": "Son of man, put forth a riddle, and speak a parable unto the house of Israel;", "ylt": "`Son of man, put forth a riddle, and use a simile unto the house of Israel,", "dra": "Son of man, put forth a riddle, and speak a parable to the house of Israel,", "bbe": "Son of man, give out a dark saying, and make a comparison for the children of Israel,", "geneva": "Sonne of man, put foorth a parable and speake a prouerbe vnto the house of Israel,", "wycliffe": "and he seide, Sone of man, sette forth a derk speche, and telle thou a parable to the hous of Israel;", "rotherham": "Son of man Put thou forth a riddle And speak thou a parable,- Unto the house of Israel:", "darby": "Son of man, put forth a riddle, and speak a parable unto the house of Israel,", "twenty": "", "jps": "'Son of man, put forth a riddle, and speak a parable unto the house of Israel,", "acv": "Son of man, put forth a riddle, and speak a parable to the house of Israel,", "anderson": "", "haweis": "", "noyes": "Son of man, put forth a riddle, and speak a parable to the house of Israel;", "webster": "Son of man, put forth a riddle, and speak a parable to the house of Israel;", "vulgate": "fili hominis propone enigma et narra parabolam ad domum Israhel;", "brenton": "Son of man, relate a tale, and speak a parable to the house of Israel:"}}, {"v": 3, "ref": "17:3", "o": "וְ/אָמַרְתָּ֞ כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הַ/נֶּ֤שֶׁר הַ/גָּדוֹל֙ גְּד֤וֹל הַ/כְּנָפַ֨יִם֙ אֶ֣רֶךְ הָ/אֵ֔בֶר מָלֵא֙ הַ/נּוֹצָ֔ה אֲשֶׁר ל֖/וֹ הָֽ/רִקְמָ֑ה בָּ֚א אֶל הַ/לְּבָנ֔וֹן וַ/יִּקַּ֖ח אֶת צַמֶּ֥רֶת הָ/אָֽרֶז", "en": {"kjv": "And say, Thus saith the Lord God; A great eagle with great wings, longwinged, full of feathers, which had divers colours, came unto Lebanon, and took the highest branch of the cedar:", "web": "and say, Thus says the Lord Yahweh: A great eagle with great wings and long feathers, full of feathers, which had various colors, came to Lebanon, and took the top of the cedar:", "bsb": "and tell them that this is what the Lord GOD says: ‘A great eagle with great wings and long pinions, full of feathers of many colors, came to Lebanon and took away the top of the cedar.", "asv": "and say, Thus saith the Lord Jehovah: A great eagle with great wings and long pinions, full of feathers, which had divers colors, came unto Lebanon, and took the top of the cedar:", "ylt": "and thou hast said: Thus said the Lord Jehovah: The great eagle, great-winged, long-pinioned, Full of feathers, that hath diverse colours, Hath come in unto Lebanon, And it taketh the foliage of the cedar,", "dra": "And say: Thus saith the Lord God; A large eagle with great wings, long-limbed, full of feathers, and of variety, came to Libanus, and took away the marrow of the cedar.", "bbe": "And say, This is what the Lord has said: A great eagle with great wings, full of long feathers of different colours, came to Lebanon, and took the top of the cedar:", "geneva": "And say, Thus saith the Lord God, The great eagle with great wings, and long wings, and ful of fethers, which had diuers colours, came vnto Lebanon, and tooke the highest branch of the cedar,", "wycliffe": "and thou schalt seie, The Lord God seith these thingis. A greet egle of grete wyngis, with long stretchyng out of membris, ful of fetheris and of dyuersite, cam to the Liban, and took awei the merowe of the cedre.", "rotherham": "So then thou shalt say, Thus, saith My Lord. Yahweh,— A great eagle, with large wings of long pinion, full of plumage, which had divers colours, came unto Lebanon, and took the highest branch of the cedar:", "darby": "and say, Thus saith the Lord Jehovah: A great eagle with great wings, long-pinioned, full of feathers, which was of divers colours, came unto Lebanon, and took the highest branch of the cedar.", "twenty": "", "jps": "and say: Thus saith the L-rd GOD: A great eagle with great wings and long pinions, full of feathers, which had divers colours, came unto Lebanon, and took the top of the cedar;", "acv": "and say, Thus says the lord Jehovah: A great eagle with great wings and long pinions, full of feathers, which had various colors, came to Lebanon, and took the top of the cedar.", "anderson": "", "haweis": "", "noyes": "and say, Thus saith the Lord Jehovah: A great eagle, with great wings, with long feathers, full of plumage, which had divers colors, came to Lebanon, and took the highest branch of a cedar.", "webster": "And say, Thus saith the Lord GOD; A great eagle with great wings, long-winged, full of feathers, which had divers colors, came to Lebanon, and took the highest branch of the cedar:", "vulgate": "et dices haec dicit Dominus Deus aquila grandis magnarum alarum longo membrorum ductu plena plumis et varietate venit ad Libanum et tulit medullam cedri;", "brenton": "and thou shalt say, Thus saith the Lord; A great eagle with large wings, spreading them out very far, with many claws, which has the design of entering into Libanus—and he took the choice branches of the cedar:"}}, {"v": 4, "ref": "17:4", "o": "אֵ֛ת רֹ֥אשׁ יְנִֽיקוֹתָ֖י/ו קָטָ֑ף וַ/יְבִיאֵ֨/הוּ֙ אֶל אֶ֣רֶץ כְּנַ֔עַן בְּ/עִ֥יר רֹכְלִ֖ים שָׂמֽ/וֹ", "en": {"kjv": "He cropped off the top of his young twigs, and carried it into a land of traffick; he set it in a city of merchants.", "web": "he cropped off the topmost of the young twigs of it, and carried it to a land of traffic; he set it in a city of merchants.", "bsb": "He plucked off its topmost shoot, carried it to the land of merchants, and planted it in a city of traders.", "asv": "he cropped off the topmost of the young twigs thereof, and carried it unto a land of traffic; he set it in a city of merchants.", "ylt": "The top of its tender twigs it hath cropped, And it bringeth it in to the land of Canaan. In a city of merchants it hath placed it.", "dra": "He cropped off the top of the twigs thereof: and carried it away into the land of Chanaan, and he set it in a city of merchants.", "bbe": "Biting off the highest of its young branches, he took it to the land of Canaan, and put it in a town of traders.", "geneva": "And brake off the toppe of his twigge, and caried it into the land of marchants, and set it in a citie of marchants.", "wycliffe": "He pullide awei the hiynesse of boowis therof, and bar it ouer in to the lond of Chanaan, and settide it in the citee of marchauntis.", "rotherham": "The crown of its young twigs, plucked he off, and brought it into a land of traffic, in a city of merchants, he set it.", "darby": "He cropped off the top of its young shoots, and carried it into a merchants' land; he set it in a city of traders.", "twenty": "", "jps": "He cropped off the topmost of the young twigs thereof, and carried it into a land of traffic; he set it in a city of merchants.", "acv": "He cropped off the topmost of the young twigs of it, and carried it to a land of merchandise. He set it in a city of merchants.", "anderson": "", "haweis": "", "noyes": "He cropped off the top of its young twigs, and carried it into a land of traffic; he set it in a city of merchants.", "webster": "He cropped off the top of its young twigs, and carried it into a land of traffick; he set it in a city of merchants.", "vulgate": "summitatem frondium eius avellit et transportavit eam in terram Chanaan in urbem negotiatorum posuit illam;", "brenton": "he cropped off the ends of the tender twigs, and brought them into the land of Chanaan; he laid them up in a walled city."}}, {"v": 5, "ref": "17:5", "o": "וַ/יִּקַּח֙ מִ/זֶּ֣רַע הָ/אָ֔רֶץ וַֽ/יִּתְּנֵ֖/הוּ בִּ/שְׂדֵה זָ֑רַע קָ֚ח עַל מַ֣יִם רַבִּ֔ים צַפְצָפָ֖ה שָׂמֽ/וֹ", "en": {"kjv": "He took also of the seed of the land, and planted it in a fruitful field; he placed it by great waters, and set it as a willow tree.", "web": "He took also of the seed of the land, and planted it in a fruitful soil; he placed it beside many waters; he set it as a willow tree.", "bsb": "He took some of the seed of the land and planted it in fertile soil; he placed it by abundant waters and set it out like a willow.", "asv": "He took also of the seed of the land, and planted it in a fruitful soil; he placed it beside many waters; he set it as a willow-tree.", "ylt": "And it taketh of the seed of the land, And doth put it in a field of seed, To take by many waters, In a conspicuous place it hath set it.", "dra": "And he took of the seed of the land, and put it in the ground for seed, that it might take a firm root over many waters: he planted it on the surface of the earth.", "bbe": "And he took some of the seed of the land, planting it in fertile earth, placing it by great waters; he put it in like a willow-tree.", "geneva": "Hee tooke also of the seede of the lande, and planted it in a fruitfull ground: hee placed it by great waters, and set it as a willowe tree.", "wycliffe": "And he took of the seed of the lond, and settide it in the lond for seed, that it schulde make stidfast roote on many watris; he settide it in the hiyere part.", "rotherham": "So he took of the seed of the land, and planted it in a field for seed,- He took it near mighty waters, Like a willow-tree, he set it.", "darby": "And he took of the seed of the land, and planted it in a fruitful field; he placed it by great waters, he set it as a willow tree.", "twenty": "", "jps": "He took also of the seed of the land, and planted it in a fruitful soil; he placed it beside many waters, he set it as a slip.", "acv": "He took also of the seed of the land, and planted it in a fruitful soil. He placed it beside many waters. He set it as a willow tree.", "anderson": "", "haweis": "", "noyes": "He took also one of the shoots of the land, and put it in a fruitful field; he placed it by great waters, and set it as a willow-tree.", "webster": "He took also of the seed of the land, and planted it in a fruitful field; he placed [it] by great waters, [and] set it [as] a willow tree.", "vulgate": "et tulit de semente terrae et posuit illud in terra pro semine ut firmaret radicem super aquas multas in superficie posuit illud;", "brenton": "And he took of the seed of the land, and sowed it in a field planted by much water; he set it in a conspicuous place."}}, {"v": 6, "ref": "17:6", "o": "וַ/יִּצְמַ֡ח וַ/יְהִי֩ לְ/גֶ֨פֶן סֹרַ֜חַת שִׁפְלַ֣ת קוֹמָ֗ה לִ/פְנ֤וֹת דָּלִיּוֹתָי/ו֙ אֵלָ֔י/ו וְ/שָׁרָשָׁ֖י/ו תַּחְתָּ֣י/ו יִֽהְי֑וּ וַ/תְּהִ֣י לְ/גֶ֔פֶן וַ/תַּ֣עַשׂ בַּדִּ֔ים וַ/תְּשַׁלַּ֖ח פֹּארֽוֹת", "en": {"kjv": "And it grew, and became a spreading vine of low stature, whose branches turned toward him, and the roots thereof were under him: so it became a vine, and brought forth branches, and shot forth sprigs.", "web": "It grew, and became a spreading vine of low stature, whose branches turned toward him, and its roots were under him: so it became a vine, and produced branches, and shot out sprigs.", "bsb": "It sprouted and became a spreading vine, low in height, with branches turned toward him; yet its roots remained where it stood. So it became a vine and yielded branches and sent out shoots.", "asv": "And it grew, and became a spreading vine of low stature, whose branches turned toward him, and the roots thereof were under him: so it became a vine, and brought forth branches, and shot forth sprigs.", "ylt": "And it springeth up, and becometh a spreading vine, humble of stature, To turn its thin shoots toward itself, And its roots are under it, And it becometh a vine, and maketh boughs, And sendeth forth beauteous branches.", "dra": "And it sprung up and grew into a spreading vine of low stature, and the branches thereof looked towards him: and the roots thereof were under him. So it became a vine, and grew into branches, and shot forth sprigs.", "bbe": "And its growth went on and it became a vine, low and widely stretching, whose branches were turned to him and its roots were under him: so it became a vine, putting out branches and young leaves.", "geneva": "And it budded vp, and was like a spreading vine of low stature, whose branches turned toward it, and the rootes thereof were vnder it: so it became a vine, and it brought foorth branches, and shot foorth buds.", "wycliffe": "And whanne it hadde growe, it encreesside in to a largere vyner, in lowe stature; for the boowis therof bihelden to that egle, and the rootis therof weren vndur that egle; therof it was maad a vyner, and it made fruyt in to siouns, and sente out boowis.", "rotherham": "And it shot forth, and became a spreading vine of lowly stature, Its branches turning towards him, And its roots under him spread,- So it became a vine, And brought forth shoots, And sent forth boughs.", "darby": "And it grew, and became a spreading vine of low stature, so that its branches should turn toward him, and the roots thereof be under him; and it became a vine, and brought forth branches, and shot forth sprigs.", "twenty": "", "jps": "And it grew, and became a spreading vine of low stature, whose tendrils might turn toward him, and the roots thereof be under him; so it became a vine, and brought forth branches, and shot forth sprigs.", "acv": "And it grew, and became a spreading vine of low stature, whose branches turned toward him, and the roots of it were under him. So it became a vine, and brought forth branches, and shot forth sprigs.", "anderson": "", "haweis": "", "noyes": "And it grew and became a spreading vine of low stature, whose branches turned towards him, and whose roots were under him. It became a vine, that brought forth branches, and shot forth boughs.", "webster": "And it grew, and became a spreading vine of low stature, whose branches turned towards him, and its roots were under him: so it became a vine, and brought forth branches, and shot forth sprigs.", "vulgate": "cumque germinasset crevit in vineam latiorem humili statura respicientibus ramis eius ad eam et radices eius sub illa erunt facta est ergo vinea et fructificavit in palmites et emisit propagines;", "brenton": "And it sprang up, and became a weak and little vine, so that the branches thereof appeared upon it, and its roots were under it: and it became a vine, and put forth shoots, and sent forth its tendrils."}}, {"v": 7, "ref": "17:7", "o": "וַ/יְהִ֤י נֶֽשֶׁר אֶחָד֙ גָּד֔וֹל גְּד֥וֹל כְּנָפַ֖יִם וְ/רַב נוֹצָ֑ה וְ/הִנֵּה֩ הַ/גֶּ֨פֶן הַ/זֹּ֜את כָּֽפְנָ֧ה שָׁרֳשֶׁ֣י/הָ עָלָ֗י/ו וְ/דָֽלִיּוֹתָי/ו֙ שִׁלְחָה לּ֔/וֹ לְ/הַשְׁק֣וֹת אוֹתָ֔/הּ מֵ/עֲרֻג֖וֹת מַטָּעָֽ/הּ", "en": {"kjv": "There was also another great eagle with great wings and many feathers: and, behold, this vine did bend her roots toward him, and shot forth her branches toward him, that he might water it by the furrows of her plantation.", "web": "There was also another great eagle with great wings and many feathers: and behold, this vine bent its roots toward him, and shot out its branches toward him, from the beds of its plantation, that he might water it.", "bsb": "But there was another great eagle with great wings and many feathers. And behold, this vine bent its roots toward him. It stretched out its branches to him from its planting bed, so that he might water it.", "asv": "There was also another great eagle with great wings and many feathers: and, behold, this vine did bend its roots toward him, and shot forth its branches toward him, from the beds of its plantation, that he might water it.", "ylt": "And there is another great eagle, Great-winged, and abounding with feathers, And lo, this vine hath bent its roots toward him, And its thin shoots it hath sent out toward him, To water it from the furrows of its planting,", "dra": "And there was another large eagle, with great wings, and many feathers: and behold this vine, bending as it were her roots towards him, stretched forth her branches to him, that he might water it by the furrows of her plantation.", "bbe": "And there was another eagle with great wings and thick feathers: and now this vine, pushing out its roots to him, sent out its branches in his direction from the bed where it was planted, so that he might give it water.", "geneva": "There was also another great eagle with great wings and many feathers, and beholde, this vine did turne her rootes toward it, and spred foorth her branches toward it, that she might water it by the trenches of her plantation.", "wycliffe": "And another greet egle was maad, with grete wyngis, and many fetheris; and lo! this vyner as sendynge hise rootis to that egle, stretchide forth his siouns to that egle, that he schulde moiste it of the cornfloris of his seed.", "rotherham": "And it came to pass that there was another great eagle, with large wings, and abundant plumage,- And lo! this vine, stretched its roots hungry towards him. And its branches, sent it forth unto him, That he might cause it to drink out of the beds where it was planted:", "darby": "And there was another great eagle with great wings and many feathers; and behold, from the beds of her plantation, this vine did bend her roots unto him, and shot forth her branches toward him, that he might water it.", "twenty": "", "jps": "There was also another great eagle with great wings and many feathers; and, behold, this vine did bend its roots toward him, and shot forth its branches toward him, from the beds of its plantation, that he might water it.", "acv": "There was also another great eagle with great wings and many feathers. And, behold, this vine bent its roots toward him, and shot forth its branches toward him, from the beds of its plantation, that he might water it.", "anderson": "", "haweis": "", "noyes": "There was also another great eagle, with great wings and many feathers; and, behold, this vine bent its roots toward him, and shot forth its branches toward him, that he might water it from the beds where it was planted.", "webster": "There was also another great eagle with great wings and many feathers: and behold, this vine did bend her roots towards him, and shot forth her branches towards him, that he might water it by the furrows of her plantation.", "vulgate": "et facta est aquila altera grandis magnis alis multisque plumis et ecce vinea ista quasi mittens radices suas ad eam palmites suos extendit ad illam ut inrigaret eam de areolis germinis sui;", "brenton": "And there was another great eagle, with great wings and many claws: and, behold, this vine bent itself round toward him, and her roots were turned towards him, and she sent forth her branches towards him, that he might water her together with the growth of her plantation."}}, {"v": 8, "ref": "17:8", "o": "אֶל שָׂ֥דֶה טּ֛וֹב אֶל מַ֥יִם רַבִּ֖ים הִ֣יא שְׁתוּלָ֑ה לַ/עֲשׂ֤וֹת עָנָף֙ וְ/לָ/שֵׂ֣את פֶּ֔רִי לִ/הְי֖וֹת לְ/גֶ֥פֶן אַדָּֽרֶת", "en": {"kjv": "It was planted in a good soil by great waters, that it might bring forth branches, and that it might bear fruit, that it might be a goodly vine.", "web": "It was planted in a good soil by many waters, that it might produce branches, and that it might bear fruit, that it might be a goodly vine.", "bsb": "It had been planted in good soil by abundant waters in order to yield branches and bear fruit and become a splendid vine.’", "asv": "It was planted in a good soil by many waters, that it might bring forth branches, and that it might bear fruit, that it might be a goodly vine.", "ylt": "On a good field, by many waters, it is planted, To make branches, and to bear fruit, To be for an goodly vine.", "dra": "It was planted in a good ground upon many waters, that it might bring forth branches, and bear fruit, that it might become a large vine.", "bbe": "He had it planted in a good field by great waters so that it might put out branches and have fruit and be a strong vine.", "geneva": "It was planted in a good soyle by great waters, that it should bring forth branches, and beare fruite, and be an excellent vine.", "wycliffe": "Which is plauntid in a good lond on many watris, that it make boowis, and bere fruyt, that it be in to a greet vyner.", "rotherham": "In a goodly field by mighty waters, was it planted,- That it might bring forth boughs, and bear fruit, That it might become a splendid vine.", "darby": "It was planted in a good field by many waters, that it might bring forth branches and bear fruit, that it might be a noble vine.", "twenty": "", "jps": "It was planted in a good soil by many waters, that it might bring forth branches, and that it might bear fruit, that it might be a stately vine.", "acv": "It was planted in a good soil by many waters that it might bring forth branches, and that it might bear fruit that it might be a goodly vine.", "anderson": "", "haweis": "", "noyes": "And yet it was planted in a good soil, by great waters, that it might bring forth branches, and that it might bear fruit, and be a goodly vine.", "webster": "It was planted in a good soil by great waters, that it might bring forth branches, and that it might bear fruit, that it might be a goodly vine.", "vulgate": "in terra bona super aquas multas plantata est ut faciat frondes et portet fructum et sit in vineam grandem;", "brenton": "She thrives in a fair field by much water, to produce shoots and bear fruit, that she might become a great vine."}}, {"v": 9, "ref": "17:9", "o": "אֱמֹ֗ר כֹּ֥ה אָמַ֛ר אֲדֹנָ֥/י יְהֹוִ֖ה תִּצְלָ֑ח הֲ/לוֹא֩ אֶת שָׁרָשֶׁ֨י/הָ יְנַתֵּ֜ק וְ/אֶת פִּרְיָ֣/הּ יְקוֹסֵ֣ס וְ/יָבֵ֗שׁ כָּל טַרְפֵּ֤י צִמְחָ/הּ֙ תִּיבָ֔שׁ וְ/לֹֽא בִ/זְרֹ֤עַ גְּדוֹלָה֙ וּ/בְ/עַם רָ֔ב לְ/מַשְׂא֥וֹת אוֹתָ֖/הּ מִ/שָּׁרָשֶֽׁי/הָ", "en": {"kjv": "Say thou, Thus saith the Lord God; Shall it prosper? shall he not pull up the roots thereof, and cut off the fruit thereof, that it wither? it shall wither in all the leaves of her spring, even without great power or many people to pluck it up by the roots thereof.", "web": "Say, Thus says the Lord Yahweh: Shall it prosper? shall he not pull up its roots, and cut off its fruit, that it may wither; that all its fresh springing leaves may wither? and not by a strong arm or many people can it be raised from its roots.", "bsb": "So you are to tell them that this is what the Lord GOD says: ‘Will it flourish? Will it not be uprooted and stripped of its fruit so that it shrivels? All its foliage will wither! It will not take a strong arm or many people to pull it up by its roots.", "asv": "Say thou, Thus saith the Lord Jehovah: Shall it prosper? shall he not pull up the roots thereof, and cut off the fruit thereof, that it may wither; that all its fresh springing leaves may wither? and not by a strong arm or much people can it be raised from the roots thereof.", "ylt": "Say: Thus said the Lord Jehovah: It prospereth--its roots doth he not draw out, And its fruit cut off, and it is withered? In all the leaves of its springing it withereth, And not by great strength, and by a numerous people, To lift it up by its roots.", "dra": "Say thou: Thus saith the Lord God: Shall it prosper then? shall he not pull up the roots thereof, and strip off its fruit, and dry up all the branches it hath shot forth, and make it wither: and this without a strong arm, or many people to pluck it up by the root?", "bbe": "Say, This is what the Lord has said: Will it do well? will he not have its roots pulled up and its branches cut off, so that all its young leaves may become dry and it may be pulled up by its roots?", "geneva": "Say thou, Thus saith the Lord God, Shall it prosper? shall he not pull vp the rootes thereof, and destroy the fruite thereof, and cause them to drie? all the leaues of her bud shall wither without great power, or many people, to plucke it vp by the rootes thereof.", "wycliffe": "Seie thou, Ezechiel, The Lord God seith these thingis, Therfor whether he schal haue prosperite? Whether Nabugodonosor schal not pulle awei the rootis of hym, and schal streyne the fruytis of hym? And he schal make drie alle the siouns of buriowning therof, and it schal be drie; and not in greet arm, nether in myche puple, that he schulde drawe it out bi the rootis.", "rotherham": "Say thou, Thus, saith My Lord Yahweh, Shall it thrive? Its roots, will he not tear up? Its fruit, will he not cut off, that it wither? All the fresh leaves it hath caused to spring forth shall wither without a strong arm or many people, to pull it up by its roots.", "darby": "Say, Thus saith the Lord Jehovah: Shall it prosper? Shall he not pull up its roots, and cut off its fruit, that it may wither? All its fresh sprouting leaves shall wither, even without a great arm and many people to pluck it up by its roots.", "twenty": "", "jps": "Say thou: Thus saith the L-rd GOD: Shall it prosper? shall he not pull up the roots thereof, and cut off the fruit thereof, that it wither, yea, wither in all its sprouting leaves? neither shall great power or much people be at hand when it is plucked up by the roots thereof.", "acv": "Say thou, Thus says the lord Jehovah: Shall it flourish? Shall he not pull up the roots of it, and cut off the fruit of it, that it may wither? It shall wither in all its fresh springing leaves, even without great power or many people to pluck it up by the roots of it.", "anderson": "", "haweis": "", "noyes": "Say thou, Thus saith the Lord Jehovah: Shall it prosper? Shall not he pull up its roots, and cut off its fruit, that it wither? In all the leaves of its branching shall it wither; even without a mighty arm, or many people, shall he pluck it up by the roots.", "webster": "Say thou, Thus saith the Lord GOD; Shall it prosper? shall he not pull up its roots, and cut off its fruit, that it may wither? it shall wither in all the leaves of her spring, even without great power or many people to pluck it up by its roots.", "vulgate": "dic haec dicit Dominus Deus ergone prosperabitur nonne radices eius evellet et fructum eius distringet et siccabit omnes palmites germinis eius et arescet et non in brachio grandi neque in populo multo ut evelleret eam radicitus;", "brenton": "Therefore say, Thus saith the Lord; Shall it prosper? shall not the roots of her tender stem and her fruit be blighted? yea, all her early shoots shall be dried up, and that not by a mighty arm, nor by many people, to tear her up from her roots."}}, {"v": 10, "ref": "17:10", "o": "וְ/הִנֵּ֥ה שְׁתוּלָ֖ה הֲ/תִצְלָ֑ח הֲ/לוֹא֩ כְ/גַ֨עַת בָּ֜/הּ ר֤וּחַ הַ/קָּדִים֙ תִּיבַ֣שׁ יָבֹ֔שׁ עַל עֲרֻגֹ֥ת צִמְחָ֖/הּ תִּיבָֽשׁ", "en": {"kjv": "Yea, behold, being planted, shall it prosper? shall it not utterly wither, when the east wind toucheth it? it shall wither in the furrows where it grew.", "web": "Yes, behold, being planted, shall it prosper? shall it not utterly wither, when the east wind touches it? it shall wither in the beds where it grew.", "bsb": "Even if it is transplanted, will it flourish? Will it not completely wither when the east wind strikes? It will wither on the bed where it sprouted.’”", "asv": "Yea, behold, being planted, shall it prosper? shall it not utterly wither, when the east wind toucheth it? it shall wither in the beds where it grew.", "ylt": "And lo, the planted thing--doth it prosper? When come against it doth the east wind, Doth it not utterly wither? On the furrows of its springing it withereth.'", "dra": "Behold, it is planted: shall it prosper then? shall it not be dried up when the burning wind shall touch it, and shall it not wither in the furrows where it grew?", "bbe": "And if it is planted will it do well? will it not become quite dry at the touch of the east wind, drying up in the bed where it was planted?", "geneva": "Beholde, it was planted: but shall it prosper? shall it not be dried vp, and wither? when the East winde shall touch it, it shall wither in the trenches, where it grewe.", "wycliffe": "Lo! it is plauntid, therfor whether it schal haue prosperite? Whether not whanne brennynge wynd schal touche it, it schal be maad drye, and schal wexe drie in the cornfloris of his seed?", "rotherham": "Lo! therefore though [it remain] planted, shall it thrive? As soon as an east wind toucheth it, will it not utterly wither? On the beds where it sprang up, will it not wither?", "darby": "And behold, being planted, shall it prosper? shall it not utterly wither when the east wind toucheth it? It shall wither in the beds where it grew.", "twenty": "", "jps": "Yea, behold, being planted, shall it prosper? Shall it not utterly wither, when the east wind toucheth it? In the beds where it grew it shall wither.'", "acv": "Yea, behold, being planted, shall it flourish? Shall it not utterly wither when the east wind touches it? It shall wither in the beds where it grew.", "anderson": "", "haweis": "", "noyes": "Yea, behold, it is planted; but shall it prosper? Shall it not utterly wither, when the east wind toucheth it? It shall wither in the beds where it grew.", "webster": "Yes, behold, [being] planted, shall it prosper? shall it not utterly wither, when the east wind toucheth it? it shall wither in the furrows where it grew.", "vulgate": "ecce plantata est ergone prosperabitur nonne cum tetigerit eam ventus urens siccabitur et in areis germinis sui arescet;", "brenton": "And, behold, it thrives: shall it prosper? shall it not wither as soon as the east wind touches it? it shall be withered together with the growth of its shoots."}}, {"v": 11, "ref": "17:11", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moreouer, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide, Seie thou to the hous terrynge to wraththe,", "rotherham": "Then came the word of Yahweh unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "Moreover the word of the Lord came to me saying,"}}, {"v": 12, "ref": "17:12", "o": "אֱמָר נָא֙ לְ/בֵ֣ית הַ/מֶּ֔רִי הֲ/לֹ֥א יְדַעְתֶּ֖ם מָה אֵ֑לֶּה אֱמֹ֗ר הִנֵּה בָ֨א מֶֽלֶךְ בָּבֶ֤ל יְרוּשָׁלִַ֨ם֙ וַ/יִּקַּ֤ח אֶת מַלְכָּ/הּ֙ וְ/אֶת שָׂרֶ֔י/הָ וַ/יָּבֵ֥א אוֹתָ֛/ם אֵלָ֖י/ו בָּבֶֽלָ/ה", "en": {"kjv": "Say now to the rebellious house, Know ye not what these things mean? tell them, Behold, the king of Babylon is come to Jerusalem, and hath taken the king thereof, and the princes thereof, and led them with him to Babylon;", "web": "Say now to the rebellious house, Don’t you know what these things mean? tell them, Behold, the king of Babylon came to Jerusalem, and took its king, and its princes, and brought them to him to Babylon:", "bsb": "“Now say to this rebellious house: ‘Do you not know what these things mean?’ Tell them, ‘Behold, the king of Babylon came to Jerusalem, carried off its king and officials, and brought them back with him to Babylon.", "asv": "Say now to the rebellious house, Know ye not what these things mean? tell them, Behold, the king of Babylon came to Jerusalem, and took the king thereof, and the princes thereof, and brought them to him to Babylon.", "ylt": "`Say, I pray thee, to the rebellious house, Have ye not known what these are ? Say, Lo, come hath the king of Babylon to Jerusalem, And he taketh its king, and its princes, And bringeth them to himself to Babylon.", "dra": "Say to the provoking house: Know you not what these things mean? Tell them: Behold the king of Babylon cometh to Jerusalem: and he shall take away the king and the princes thereof and carry them with him to Babylon.", "bbe": "Say now to this uncontrolled people, Are these things not clear to you? Say to them, See, the king of Babylon came to Jerusalem and took its king and its rulers away with him to Babylon;", "geneva": "Say now to this rebellious house, Know ye not, what these things meane? tell them, Behold, the King of Babel is come to Ierusalem, and hath taken the King thereof, and the princes thereof, and led them with him to Babel,", "wycliffe": "Witen ye not what these thingis signefien? Seie thou, Lo! the king of Babiloyne cometh in to Jerusalem; and he schal take the kyng and the princis therof, and he schal leede hem to hym silf in to Babiloyne.", "rotherham": "Say, I pray thee unto the perverse house, Know ye not what these things are? Say thou Lo! the King of Babylon entered Jerusalem And took her king and her princes, And brought them unto him in Babylon;", "darby": "Say now to the rebellious house, Know ye not what these things are? Say, Behold, the king of Babylon came to Jerusalem, and took its king and its princes, and led them with him to Babylon.", "twenty": "", "jps": "'Say now to the rebellious house: Know ye not what these things mean? tell them: Behold, the king of Babylon came to Jerusalem, and took the king thereof, and the princes thereof, and brought them to him to Babylon;", "acv": "Say now to the rebellious house, Know ye not what these things mean? Tell them, Behold, the king of Babylon came to Jerusalem, and took the king of it, and the rulers of it, and brought them to him to Babylon.", "anderson": "", "haweis": "", "noyes": "Say now to the rebellious house, Know ye not what these things mean? Say, behold, the king of Babylon came to Jerusalem, and took her king and her princes, and led them with him to Babylon,", "webster": "Say now to the rebellious house, Know ye not what these [things mean]? tell [them], Behold, the king of Babylon hath come to Jerusalem, and hath taken its king, and its princes, and led them with him to Babylon;", "vulgate": "dic ad domum exasperantem nescitis quid ista significent dic ecce venit rex Babylonis Hierusalem et adsumet regem et principes eius et adducet eos ad semet ipsum in Babylonem;", "brenton": "Son of man, say now to the provoking house, Know ye not what these things were? say to them, Whenever the king of Babylon shall come against Jerusalem, then he shall take her king and her princes, and shall take them home to Babylon."}}, {"v": 13, "ref": "17:13", "o": "וַ/יִּקַּח֙ מִ/זֶּ֣רַע הַ/מְּלוּכָ֔ה וַ/יִּכְרֹ֥ת אִתּ֖/וֹ בְּרִ֑ית וַ/יָּבֵ֤א אֹת/וֹ֙ בְּ/אָלָ֔ה וְ/אֶת אֵילֵ֥י הָ/אָ֖רֶץ לָקָֽח", "en": {"kjv": "And hath taken of the king’s seed, and made a covenant with him, and hath taken an oath of him: he hath also taken the mighty of the land:", "web": "and he took of the seed royal, and made a covenant with him; he also brought him under an oath, and took away the mighty of the land;", "bsb": "He took a member of the royal family and made a covenant with him, putting him under oath. Then he carried away the leading men of the land,", "asv": "And he took of the seed royal, and made a covenant with him; he also brought him under an oath, and took away the mighty of the land;", "ylt": "And he taketh of the seed of the kingdom, And maketh with him a covenant, And bringeth him in to an oath, And the mighty of the land he hath taken,", "dra": "And he shall take one of the king's seed, and make a covenant with him, and take an oath of him. Yea, and he shall take away the mighty men of the land,", "bbe": "And he took one of the sons of the king and made an agreement with him; and he put him under an oath, and took away the great men of the land:", "geneva": "And hath taken one of the Kings seede, and made a couenant with him, and hath taken an othe of him: he hath also taken the princes of the land,", "wycliffe": "And he schal take of the seed of the rewme, and schal smyte with it a boond of pees, and he schal take of it an ooth; but also he schal take awei the stronge men of the lond,", "rotherham": "Yea took of the seed royal And solemnised with him a covenant, And brought him into an oath, Also the mighty ones of the land, did he take.", "darby": "And he took of the king's seed, and made a covenant with him, and brought him under an oath, and he took away the mighty of the land;", "twenty": "", "jps": "and he took of the seed royal, and made a covenant with him, and brought him under an oath, and the mighty of the land he took away;", "acv": "And he took of the seed royal, and made a covenant with him. He also brought him under an oath, and took away the mighty of the land,", "anderson": "", "haweis": "", "noyes": "and took one of the king’s offspring, and made a covenant with him, and took an oath of him, and the mighty of the land he took away,", "webster": "And hath taken of the king's seed, and made a covenant with him, and hath taken an oath from him: he hath also taken the mighty of the land:", "vulgate": "et tollet de semine regni ferietque cum eo foedus et accipiet ab eo iusiurandum sed et fortes terrae tollet;", "brenton": "And he shall take of the seed royal, and shall make a covenant with him, and shall bind him with an oath: and he shall take the princes of the land:"}}, {"v": 14, "ref": "17:14", "o": "לִֽ/הְיוֹת֙ מַמְלָכָ֣ה שְׁפָלָ֔ה לְ/בִלְתִּ֖י הִתְנַשֵּׂ֑א לִ/שְׁמֹ֥ר אֶת בְּרִית֖/וֹ לְ/עָמְדָֽ/הּ", "en": {"kjv": "That the kingdom might be base, that it might not lift itself up, but that by keeping of his covenant it might stand.", "web": "that the kingdom might be base, that it might not lift itself up, but that by keeping his covenant it might stand.", "bsb": "so that the kingdom would be brought low, unable to lift itself up, surviving only by keeping his covenant.", "asv": "that the kingdom might be base, that it might not lift itself up, but that by keeping his covenant it might stand.", "ylt": "That the kingdom may be humble, That it may not lift itself up, To keep his covenant--that it may stand.", "dra": "That it may be a low kingdom and not lift itself up, but keep his covenant and observe it.", "bbe": "So that the kingdom might be made low with no power of lifting itself up, but might keep his agreement to be his servants.", "geneva": "That the kingdome might be in subiection, and not lift it selfe vp, but keepe their couenant, and stand to it.", "wycliffe": "that it be a meke rewme, and be not reisid, but that it kepe the couenaunt of hym, and holde it.", "rotherham": "That, the kingdom might be abased, so as not to lift itself up,— By the keeping of his covenant, might be made to stand.", "darby": "that the kingdom might be abased, that it might not lift itself up, that it might keep his covenant in order to stand.", "twenty": "", "jps": "that his might be a lowly kingdom, that it might not lift itself up, but that by keeping his covenant it might stand.", "acv": "that the kingdom might be base, that it might not lift itself up, but that by keeping his covenant it might stand.", "anderson": "", "haweis": "", "noyes": "that the kingdom might be brought low, so as not to lift itself up; that the covenant might be kept, and stand.", "webster": "That the kingdom might be base, that it might not lift itself up, [but] that by keeping his covenant it might stand.", "vulgate": "ut sit regnum humile et non elevetur sed custodiat pactum eius et servet illud;", "brenton": "that it may become a weak kingdom, so as never to lift itself up, that he may keep his covenant, and establish it."}}, {"v": 15, "ref": "17:15", "o": "וַ/יִּמְרָד בּ֗/וֹ לִ/שְׁלֹ֤חַ מַלְאָכָי/ו֙ מִצְרַ֔יִם לָֽ/תֶת ל֥/וֹ סוּסִ֖ים וְ/עַם רָ֑ב הֲ/יִצְלָ֤ח הֲ/יִמָּלֵט֙ הָ/עֹשֵׂ֣ה אֵ֔לֶּה וְ/הֵפֵ֥ר בְּרִ֖ית וְ/נִמְלָֽט", "en": {"kjv": "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? shall he escape that doeth such things? or shall he break the covenant, and be delivered?", "web": "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and many people. Shall he prosper? shall he escape who does such things? shall he break the covenant, and yet escape?", "bsb": "But this king rebelled against Babylon by sending his envoys to Egypt to ask for horses and a large army. Will he flourish? Will the one who does such things escape? Can he break a covenant and yet escape?’", "asv": "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? shall he escape that doeth such things? shall he break the covenant, and yet escape?", "ylt": "And he rebelleth against him, To send his messengers to Egypt, To give to him horses, and much people, Doth he prosper? doth he escape who is doing these things? And hath he broken covenant and escaped?", "dra": "But he hath revolted from him and sent ambassadors to Egypt, that it might give him horses, and much people. And shall he that hath done thus prosper, or be saved? and shall he escape that hath broken the covenant?", "bbe": "But he went against his authority in sending representatives to Egypt to get from them horses and a great army. Will he do well? will he be safe who does such things? if the agreement is broken will he be safe?", "geneva": "But he rebelled against him, and sent his ambassadours into Egypt, that they might giue him horses, and much people: shall hee prosper? shall he escape, that doeth such things? or shall he breake the couenant, and be deliuered?", "wycliffe": "Which yede awei fro hym, and sente messangeris in to Egipt, that it schulde yyue to hym horsis and miche puple. Whether he that dide these thingis, schal haue prosperite, ether schal gete helthe? and whether he that brekith couenaunt, schal ascape?", "rotherham": "But he hath rebelled against him by sending his messengers to Egypt, that there should be given to him horses, and much people. Shall he thrive? Shall he escape that doeth these things? Shall he break a covenant and escape?", "darby": "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? shall he escape that doeth such things? shall he break the covenant, and yet escape?", "twenty": "", "jps": "But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? shall he escape that doeth such things? shall he break the covenant, and yet escape?", "acv": "But he rebelled against him in sending his ambassadors into Egypt that they might give him horses and many people. Shall he prosper? Shall he escape who does such things? Shall he break the covenant, and yet escape?", "anderson": "", "haweis": "", "noyes": "But he rebelled against him, in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? Shall he escape that doeth such things? Shall he break the covenant and be delivered?", "webster": "But he rebelled against him in sending his embassadors into Egypt, that they might give him horses and many people. Shall he prosper? shall he escape that doeth such [things]? or shall he break the covenant, and be delivered?", "vulgate": "qui recedens ab eo misit nuntios ad Aegyptum ut daret sibi equos et populum multum numquid prosperabitur vel consequetur salutem qui fecit haec et qui dissolvit pactum numquid effugiet;", "brenton": "And if he shall revolt from him, to send his messengers into Egypt, that they may give him horses and much people; shall he prosper? shall he that acts as an adversary be preserved? and shall he that transgresses the covenant be preserved?"}}, {"v": 16, "ref": "17:16", "o": "חַי אָ֗נִי נְאֻם֮ אֲדֹנָ֣/י יְהוִה֒ אִם לֹ֗א בִּ/מְקוֹם֙ הַ/מֶּ֨לֶךְ֙ הַ/מַּמְלִ֣יךְ אֹת֔/וֹ אֲשֶׁ֤ר בָּזָה֙ אֶת אָ֣לָת֔/וֹ וַ/אֲשֶׁ֥ר הֵפֵ֖ר אֶת בְּרִית֑/וֹ אִתּ֥/וֹ בְ/תוֹךְ בָּבֶ֖ל יָמֽוּת", "en": {"kjv": "As I live, saith the Lord God, surely in the place where the king dwelleth that made him king, whose oath he despised, and whose covenant he brake, even with him in the midst of Babylon he shall die.", "web": "As I live, says the Lord Yahweh, surely in the place where the king dwells who made him king, whose oath he despised, and whose covenant he broke, even with him in the midst of Babylon he shall die.", "bsb": "‘As surely as I live,’ declares the Lord GOD, ‘he will die in Babylon, in the land of the king who enthroned him, whose oath he despised and whose covenant he broke.", "asv": "As I live, saith the Lord Jehovah, surely in the place where the king dwelleth that made him king, whose oath he despised, and whose covenant he brake, even with him in the midst of Babylon he shall die.", "ylt": "I live--an affirmation of the Lord Jehovah, Doth he not--in the place of the king who is causing him to reign, Whose oath he hath despised, And whose covenant he hath broken, With him--in the midst of Babylon--die?", "dra": "As I live, saith the Lord God: In the place where the king dwelleth that made him king, whose oath he hath made void, and whose covenant he broke, even in the midst of Babylon shall he die.", "bbe": "By my life, says the Lord, truly in the place of the king who made him king, whose oath he put on one side and let his agreement with him be broken, even in Babylon he will come to his death.", "geneva": "As I liue, saith the Lord God, he shall die in the middes of Babel, in the place of the King, that had made him King, whose othe he despised, and whose couenant made with him, he brake.", "wycliffe": "Y lyue, seith the Lord God, for in the place of the king that made hym kyng, whos ooth he made voide, and brak the couenaunt, which he hadde with hym, in the myddis of Babiloyne he schal die.", "rotherham": "As I live, Declareth My Lord Yahweh, Very! in the place where dwelleth the king that made him king, Whose oath he hath despised, And whose covenant he hath broken With him in the midst of Babylon, shall he die.", "darby": "[As] I live, saith the Lord Jehovah, verily in the place of the king that made him king, whose oath he despised, and whose covenant he broke, even with him, in the midst of Babylon, shall he die.", "twenty": "", "jps": "As I live, saith the L-rd GOD, surely in the place where the king dwelleth that made him king, whose oath he despised, and whose covenant he broke, even with him in the midst of Babylon he shall die.", "acv": "As I live, says the lord Jehovah, surely in the place where the king dwells who made him king, whose oath he despised, and whose covenant he broke, even with him in the midst of Babylon he shall die.", "anderson": "", "haweis": "", "noyes": "As I live saith the Lord Jehovah, surely in the place where the king dwelleth that made him king, whose oath he despised, and whose covenant he broke, even with him in the midst of Babylon shall he die.", "webster": "[As] I live, saith the Lord GOD, surely in the place [where] the king [dwelleth] that made him king, whose oath he despised, and whose covenant he broke, [even] with him in the midst of Babylon he shall die.", "vulgate": "vivo ego dicit Dominus Deus quoniam in loco regis qui constituit eum regem cuius fecit irritum iuramentum et solvit pactum quod habebat cum eo in medio Babylonis morietur;", "brenton": "As I live, saith the Lord, verily in the place where the king is that made him king, who dishonoured my oath, and who broke my covenant, shall he die with him in the midst of Babylon."}}, {"v": 17, "ref": "17:17", "o": "וְ/לֹא֩ בְ/חַ֨יִל גָּד֜וֹל וּ/בְ/קָהָ֣ל רָ֗ב יַעֲשֶׂ֨ה אוֹת֤/וֹ פַרְעֹה֙ בַּ/מִּלְחָמָ֔ה בִּ/שְׁפֹּ֥ךְ סֹלְלָ֖ה וּ/בִ/בְנ֣וֹת דָּיֵ֑ק לְ/הַכְרִ֖ית נְפָשׁ֥וֹת רַבּֽוֹת", "en": {"kjv": "Neither shall Pharaoh with his mighty army and great company make for him in the war, by casting up mounts, and building forts, to cut off many persons:", "web": "Neither shall Pharaoh with his mighty army and great company help him in the war, when they cast up mounds and build forts, to cut off many persons.", "bsb": "Pharaoh with his mighty army and vast horde will not help him in battle, when ramps are built and siege walls constructed to destroy many lives.", "asv": "Neither shall Pharaoh with his mighty army and great company help him in the war, when they cast up mounds and build forts, to cut off many persons.", "ylt": "And not with a great force, and with a numerous assembly, Doth Pharaoh maintain him in battle, By pouring out a mount, and in building a fortification, To cut off many souls.", "dra": "And not with a great army, nor with much people shall Pharao fight against him: when he shall cast up mounts, and build forts, to cut off many souls.", "bbe": "And Pharaoh with his strong army and great forces will be no help to him in the war, when they put up earthworks and make strong walls for the cutting off of lives:", "geneva": "Neither shall Pharaoh with his mightie hoste, and great multitude of people, mainteine him in the warre, when they haue cast vp mounts, and builded ramparts to destroy many persons.", "wycliffe": "And not in greet oost, nether in myche puple Farao schal make batel ayens hym, in the castyng of erthe, and in bildyng of palis, that he sle many persones.", "rotherham": "Neither shall Pharaoh with a great force. or with a large gathered host, work with him in the war, by casting up an earthwork and by building a siege-wall, —to the cuting off of many lives.", "darby": "Neither shall Pharaoh with a mighty army and a great assemblage do anything for him in the war, when they cast up mounds and build forts to cut off many persons.", "twenty": "", "jps": "Neither shall Pharaoh with his mighty army and great company succour him in the war, when they cast up mounds and build forts, to cut off many souls;", "acv": "Nor shall Pharaoh with his mighty army and great company help him in the war when they cast up mounds and build forts to cut off many persons.", "anderson": "", "haweis": "", "noyes": "Neither shall Pharaoh with his mighty army and great multitude accomplish anything for him in war, when they shall cast up mounds, and build forts to cut off many persons,", "webster": "Neither shall Pharaoh with [his] mighty army and great company make for him in the war, by casting up mounts, and building forts, to cut off many persons:", "vulgate": "et non in exercitu grandi neque in populo multo faciet contra eum Pharao proelium in iactu aggeris et in extructione vallorum ut interficiat animas multas;", "brenton": "And Pharaoh shall make war upon him not with a large force or great multitude, in throwing up a mound, and in building of forts, to cut off souls."}}, {"v": 18, "ref": "17:18", "o": "וּ/בָזָ֥ה אָלָ֖ה לְ/הָפֵ֣ר בְּרִ֑ית וְ/הִנֵּ֨ה נָתַ֥ן יָד֛/וֹ וְ/כָל אֵ֥לֶּה עָשָׂ֖ה לֹ֥א יִמָּלֵֽט", "en": {"kjv": "Seeing he despised the oath by breaking the covenant, when, lo, he had given his hand, and hath done all these things, he shall not escape.", "web": "For he has despised the oath by breaking the covenant; and behold, he had given his hand, and yet has done all these things; he shall not escape.", "bsb": "He despised the oath by breaking the covenant. Seeing that he gave his hand in pledge yet did all these things, he will not escape!’", "asv": "For he hath despised the oath by breaking the covenant; and behold, he had given his hand, and yet hath done all these things; he shall not escape.", "ylt": "And he despised the oath--to break covenant, And lo, he hath given his hand, And all these he hath done, he escapeth not.", "dra": "For he had despised the oath, breaking his covenant, and behold he hath given his hand: and having done all these things, he shall not escape.", "bbe": "For he put his oath on one side in letting the agreement be broken; and though he had given his hand to it, he did all these things; he will not get away safe.", "geneva": "For he hath despised the othe, and broken ye couenant (yet lo, he had giuen his hand) because he hath done all these things, he shall not escape.", "wycliffe": "For he dispiside the ooth, that he schulde breke the boond of pees, and lo! he yaf his hond; and whanne he hath do alle these thingis, he schal not ascape.", "rotherham": "Seeing he hath despised an oath. by breaking a covenant—yea lo! hath given his hand and all these things hath done he shall not escape.", "darby": "He despised the oath, and broke the covenant; and behold, he had given his hand, yet hath he done all these things: he shall not escape.", "twenty": "", "jps": "seeing he hath despised the oath by breaking the covenant, when, lo, he had given his hand, and hath done all these things, he shall not escape.", "acv": "For he has despised the oath by breaking the covenant. And, behold, he had given his hand, and yet has done all these things. He shall not escape.", "anderson": "", "haweis": "", "noyes": "he hath despised the oath, and broken the covenant; behold, he hath given the hand, and yet done all these things; he shall not escape!", "webster": "Seeing he despised the oath by breaking the covenant, when lo, he had given his hand, and hath done all these [things], he shall not escape.", "vulgate": "spreverat enim iuramentum ut solveret foedus et ecce dedit manum suam et cum omnia haec fecerit non effugiet;", "brenton": "Whereas he has profaned the oath so as to break the covenant, when, behold, I engage his hand, and he has done all these things to him, he shall not escape."}}, {"v": 19, "ref": "17:19", "o": "לָ/כֵ֞ן כֹּה אָמַ֨ר אֲדֹנָ֣/י יְהוִה֮ חַי אָנִי֒ אִם לֹ֗א אָֽלָתִ/י֙ אֲשֶׁ֣ר בָּזָ֔ה וּ/בְרִיתִ֖/י אֲשֶׁ֣ר הֵפִ֑יר וּ/נְתַתִּ֖י/ו בְּ/רֹאשֽׁ/וֹ", "en": {"kjv": "Therefore thus saith the Lord God; As I live, surely mine oath that he hath despised, and my covenant that he hath broken, even it will I recompense upon his own head.", "web": "Therefore thus says the Lord Yahweh: As I live, surely my oath that he has despised, and my covenant that he has broken, I will even bring it on his own head.", "bsb": "Therefore this is what the Lord GOD says: ‘As surely as I live, I will bring down upon his head My oath that he despised and My covenant that he broke.", "asv": "Therefore thus saith the Lord Jehovah: As I live, surely mine oath that he hath despised, and my covenant that he hath broken, I will even bring it upon his own head.", "ylt": "Therefore, thus said the Lord Jehovah: I live--Mine oath that he hath despised, And My covenant that he hath broken, Have I not put it on his head?", "dra": "Therefore thus saith the Lord God: As I live, I will lay upon his head the oath he hath despised, and the covenant he hath broken.", "bbe": "And so the Lord has said, By my life, truly, for my oath which he put on one side, and my agreement which has been broken, I will send punishment on his head.", "geneva": "Therefore, thus sayth the Lord God, As I liue, I wil surely bring mine othe that he hath despised, and my couenant that he hath broken vpon his owne head.", "wycliffe": "Therfor the Lord God seith these thingis, Y lyue, for Y schal sette on his heed the ooth which he dispiside, and the boond of pees which he brak.", "rotherham": "Therefore, Thus saith My Lord Yahweh As I live, Surely it is mine oath which he hath despised, and my covenant which he hath broken, Therefore will I bring it upon his own head:", "darby": "Therefore thus saith the Lord Jehovah: [As] I live, verily, mine oath which he hath despised, and my covenant which he hath broken, even it will I recompense upon his head.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: As I live, surely Mine oath that he hath despised, and My covenant that he hath broken, I will even bring it upon his own head.", "acv": "Therefore thus says the lord Jehovah: As I live, surely my oath that he has despised, and my covenant that he has broken, I will even bring it upon his own head.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: As I live, surely mine oath, which he hath despised, and my covenant, which he hath broken, will I recompense upon his own head.", "webster": "Therefore thus saith the Lord GOD; [As] I live, surely my oath that he hath despised, and my covenant that he hath broken, even that will I recompense upon his own head.", "vulgate": "propterea haec dicit Dominus Deus vivo ego quoniam iuramentum quod sprevit et foedus quod praevaricatus est ponam in caput eius;", "brenton": "Therefore say, Thus saith the Lord; As I live, surely mine oath which he has profaned, and my covenant which he has transgressed, I will even recompense it upon his head."}}, {"v": 20, "ref": "17:20", "o": "וּ/פָרַשְׂתִּ֤י עָלָי/ו֙ רִשְׁתִּ֔/י וְ/נִתְפַּ֖שׂ בִּ/מְצֽוּדָתִ֑/י וַ/הֲבִיאוֹתִ֣י/הוּ בָבֶ֗לָ/ה וְ/נִשְׁפַּטְתִּ֤י אִתּ/וֹ֙ שָׁ֔ם מַעֲל֖/וֹ אֲשֶׁ֥ר מָֽעַל בִּֽ/י", "en": {"kjv": "And I will spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, and will plead with him there for his trespass that he hath trespassed against me.", "web": "I will spread my net on him, and he shall be taken in my snare, and I will bring him to Babylon, and will enter into judgment with him there for his trespass that he has trespassed against me.", "bsb": "I will spread My net over him and catch him in My snare. I will bring him to Babylon and execute judgment upon him there for the treason he committed against Me.", "asv": "And I will spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, and will enter into judgment with him there for his trespass that he hath trespassed against me.", "ylt": "And I have spread out for him My snare, And he hath been caught in My net, And I have brought him in to Babylon, And pleaded with him there his trespass, That he hath trespassed against Me.", "dra": "And I will spread my net over him, and he shall be taken in my net: and I will bring him into Babylon, and will judge him there for the transgression by which he hath despised me.", "bbe": "My net will be stretched out over him, and he will be taken in my cords, and I will send him to Babylon, and there I will be his judge for the wrong which he has done against me.", "geneva": "And I wil spread my net vpon him, and he shalbe taken in my net, and I wil bring him to Babel, and will enter into iudgement with him there for his trespas that he hath committed against me.", "wycliffe": "And Y schal spredde abrood my net on hym, and he schal be takun in my net, and Y schal brynge hym in to Babiloyne; and there Y schal deme hym in the trespassyng, bi which he dispiside me.", "rotherham": "And I will spread over him my net, And he shall be taken in my snare, And I will bring him into Babylon and will enter into judgment with him there, as to his treachery wherewith he hath been treacherous against me;", "darby": "And I will spread my net upon him, and he shall be taken in my snare; and I will bring him to Babylon, and will enter into judgment with him there for his unfaithfulness in which he hath been unfaithful against me.", "twenty": "", "jps": "And I will spread My net upon him, and he shall be taken in My snare, and I will bring him to Babylon, and will plead with him there for his treachery that he hath committed against Me.", "acv": "And I will spread my net upon him, and he shall be taken in my snare. And I will bring him to Babylon, and will enter into judgment with him there for his trespass that he has trespassed against me.", "anderson": "", "haweis": "", "noyes": "And I will spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, and will contend with him there for his trespass which he hath committed against me.", "webster": "And I will spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, and will plead with him there for his trespass that he hath trespassed against me.", "vulgate": "et expandam super eum rete meum et conprehendetur sagena mea et adducam eum in Babylonem et iudicabo illum ibi in praevaricatione qua despexit me;", "brenton": "And I will spread a net upon him, and he shall be caught in its snare."}}, {"v": 21, "ref": "17:21", "o": "וְ/אֵ֨ת כָּל מברח/ו מִבְרָחָ֤י/ו בְּ/כָל אֲגַפָּי/ו֙ בַּ/חֶ֣רֶב יִפֹּ֔לוּ וְ/הַ/נִּשְׁאָרִ֖ים לְ/כָל ר֣וּחַ יִפָּרֵ֑שׂוּ וִ/ידַעְתֶּ֕ם כִּ֛י אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "And all his fugitives with all his bands shall fall by the sword, and they that remain shall be scattered toward all winds: and ye shall know that I the Lord have spoken it.", "web": "All his fugitives in all his bands shall fall by the sword, and those who remain shall be scattered toward every wind: and you shall know that I, Yahweh, have spoken it.", "bsb": "All his choice troops will fall by the sword, and those who survive will be scattered to every wind. Then you will know that I, the LORD, have spoken.’", "asv": "And all his fugitives in all his bands shall fall by the sword, and they that remain shall be scattered toward every wind: and ye shall know that I, Jehovah, have spoken it.", "ylt": "And all his fugitives, with all his bands, By sword do fall, and those remaining, To every wind they are spread out, And ye have known that I, Jehovah, have spoken.", "dra": "And all his fugitives with all his bands shall fall by the sword: and the residue shall be scattered into every wind: and you shall know that I the Lord have spoken.", "bbe": "All his best fighting-men will be put to the sword, and the rest will be sent away to every wind: and you will be certain that I the Lord have said it.", "geneva": "And all that flee from him with all his hoste, shall fall by the sword, and they that remaine, shalbe scattered towarde all the windes: and ye shall know that I the Lord haue spoken it.", "wycliffe": "And alle hise flieris a wei with al his cumpenye schulen falle doun bi swerd, forsothe the remenauntis schulen be schaterid in to ech wynd; and ye schulen wite, that Y the Lord spak.", "rotherham": "And all his fugitives throughout all his bands by the sword, shall fall, And they who are left, to every wind, shall be scattered,- [So shall ye know that I, Yahweh, have spoken!]", "darby": "And all his fugitives with all his bands shall fall by the sword, and they that remain shall be scattered toward every wind; and ye shall know that I Jehovah have spoken.", "twenty": "", "jps": "And all his mighty men in all his bands shall fall by the sword, and they that remain shall be scattered toward every wind; and ye shall know that I HaShem have spoken it.", "acv": "And all his fugitives in all his groups shall fall by the sword, and those who remain shall be scattered toward every wind. And ye shall know that I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "And all his fugitives with all his hosts shall fall by the sword, and they that remain shall be scattered to all the winds; and ye shall know that I, Jehovah, have spoken it.", "webster": "And all his fugitives with all his bands shall fall by the sword, and they that remain shall be scattered towards all winds: and ye shall know that I the LORD have spoken [it].", "vulgate": "et omnes profugi eius cum universo agmine gladio cadent residui autem in omnem ventum dispergentur et scietis quia ego Dominus locutus sum;", "brenton": "In every battle of his they shall fall by the sword, and I will scatter his remnant to every wind: and ye shall know that I the Lord have spoken it."}}, {"v": 22, "ref": "17:22", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה וְ/לָקַ֣חְתִּי אָ֗נִי מִ/צַּמֶּ֧רֶת הָ/אֶ֛רֶז הָ/רָמָ֖ה וְ/נָתָ֑תִּי מֵ/רֹ֤אשׁ יֹֽנְקוֹתָי/ו֙ רַ֣ךְ אֶקְטֹ֔ף וְ/שָׁתַ֣לְתִּי אָ֔נִי עַ֥ל הַר גָּבֹ֖הַ וְ/תָלֽוּל", "en": {"kjv": "Thus saith the Lord God; I will also take of the highest branch of the high cedar, and will set it; I will crop off from the top of his young twigs a tender one, and will plant it upon an high mountain and eminent:", "web": "Thus says the Lord Yahweh: I will also take of the lofty top of the cedar, and will set it; I will crop off from the topmost of its young twigs a tender one, and I will plant it on a high and lofty mountain:", "bsb": "This is what the Lord GOD says: ‘I will take a shoot from the lofty top of the cedar, and I will set it out. I will pluck a tender sprig from its topmost shoots, and I will plant it on a high and lofty mountain.", "asv": "Thus saith the Lord Jehovah: I will also take of the lofty top of the cedar, and will set it; I will crop off from the topmost of its young twigs a tender one, and I will plant it upon a high and lofty mountain:", "ylt": "Thus said the Lord Jehovah: I have taken of the foliage of the high cedar, And I have set it , From the top of its tender shoots a tender one I crop, And I--I have planted it on a mountain high and lofty.", "dra": "Thus saith the Lord God: I myself will take of the marrow of the high cedar, and will set it: I will crop off a tender twig from the top of the branches thereof, and I will plant it on a mountain high and eminent.", "bbe": "This is what the Lord has said: Further, I will take the highest top of the cedar and put it in the earth; cutting off from the highest of his young branches a soft one, I will have it planted on a high and great mountain;", "geneva": "Thus saith the Lord God, I wil also take off the top of this hie cedar, and wil set it, and cut off the top of the tender plant thereof, and I wil plant it vpon an hie mountaine and great.", "wycliffe": "The Lord God seith these thingis, And Y schal take of the merowe of an hiy cedre, and Y schal sette a tendir thing of the cop of hise braunchis; Y schal streyne, and Y schal plaunte on an hiy hil, and apperynge fer.", "rotherham": "Thus, saith My Lord Yahweh, Therefore will I, Myself, take of the highest branch of the lofty cedar and set it,— Of the crown of its young twigs, a tender one, will I pluck off, and I. myself will plant it upon a mountain high and terraced,", "darby": "Thus saith the Lord Jehovah: I will also take of the highest branch of the lofty cedar, and will set it; I will crop off from the top of its young shoots a tender one, and I will plant it upon a high and eminent mountain:", "twenty": "", "jps": "Thus saith the L-rd GOD: Moreover I will take, even I, of the lofty top of the cedar, and will set it; I will crop off from the topmost of its young twigs a tender one, and I will plant it upon a high mountain and eminent;", "acv": "Thus says the lord Jehovah: I will also take of the lofty top of the cedar, and will set it. I will crop off a tender one from the topmost of its young twigs, and I will plant it upon a high and lofty mountain.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I also will take from the top of the high cedar, and will get it; and from the highest of its twigs will I crop a tender one, and plant it upon a high and lofty mountain.", "webster": "Thus saith the Lord GOD, I will also take of the highest branch of the high cedar, and will set [it]; I will crop off from the top of its young twigs a tender one, and will plant [it] upon a high mountain and eminent:", "vulgate": "haec dicit Dominus Deus et sumam ego de medulla cedri sublimis et ponam de vertice ramorum eius tenerum distringam et plantabo super montem excelsum et eminentem;", "brenton": "For thus saith the Lord; I will even take of the choice branches of the cedar from the top thereof, I will crop off their hearts, and I will plant it on a high mountain:"}}, {"v": 23, "ref": "17:23", "o": "בְּ/הַ֨ר מְר֤וֹם יִשְׂרָאֵל֙ אֶשְׁתֳּלֶ֔/נּוּ וְ/נָשָׂ֤א עָנָף֙ וְ/עָ֣שָׂה פֶ֔רִי וְ/הָיָ֖ה לְ/אֶ֣רֶז אַדִּ֑יר וְ/שָׁכְנ֣וּ תַחְתָּ֗י/ו כֹּ֚ל צִפּ֣וֹר כָּל כָּנָ֔ף בְּ/צֵ֥ל דָּלִיּוֹתָ֖י/ו תִּשְׁכֹּֽנָּה", "en": {"kjv": "In the mountain of the height of Israel will I plant it: and it shall bring forth boughs, and bear fruit, and be a goodly cedar: and under it shall dwell all fowl of every wing; in the shadow of the branches thereof shall they dwell.", "web": "in the mountain of the height of Israel will I plant it; and it shall produce boughs, and bear fruit, and be a goodly cedar: and under it shall dwell all birds of every wing; in the shade of its branches shall they dwell.", "bsb": "I will plant it on the mountain heights of Israel so that it will bear branches; it will yield fruit and become a majestic cedar. Birds of every kind will nest under it, taking shelter in the shade of its branches.", "asv": "in the mountain of the height of Israel will I plant it; and it shall bring forth boughs, and bear fruit, and be a goodly cedar: and under it shall dwell all birds of every wing; in the shade of the branches thereof shall they dwell.", "ylt": "In a mountain--the high place of Israel, I plant it, And it hath borne boughs, and yielded fruit, And become a goodly cedar, And dwelt under it have all birds of every wing, In the shade of its thin shoots they dwell.", "dra": "On the high mountains of Israel will I plant it, and it shall shoot forth into branches and shall bear fruit, and it shall become a great cedar: and all birds shall dwell under it, and every fowl shall make its nest under the shadow of the branches thereof.", "bbe": "It will be planted on the high mountain of Israel: it will put out branches and have fruit and be a fair cedar: under it all birds of every sort will make their living-place, resting in the shade of its branches.", "geneva": "Euen in the hie mountaine of Israel will I plant it: and it shall bring forth boughes and beare fruite, and be an excellent cedar, and vnder it shall remaine all birds, and euery foule shall dwell in the shadow of the branches thereof.", "wycliffe": "In the hiy hil of Israel Y schal plaunte it; and it schal breke out in to buriownyng, and it schal make fruyt, and it schal be in to a greet cedre, and alle briddis schulen dwelle vndur it; ech volatil schal make nest vndur the schadewe of hise boowis.", "rotherham": "In the mountain of the height of Israel, will I plant it, And it shall put forth boughs And bear fruit, And become a majestic cedar,- And every bird of every wing shall dwell under it, In the shade of its branches, shall they dwell.", "darby": "upon the mountain of the height of Israel will I plant it; and it shall bring forth branches, and bear fruit, and become a noble cedar; and under it shall dwell all birds of every wing; in the shadow of the branches thereof shall they dwell.", "twenty": "", "jps": "in the mountain of the height of Israel will I plant it; and it shall bring forth boughs, and bear fruit, and be a stately cedar; and under it shall dwell all fowl of every wing, in the shadow of the branches thereof shall they dwell.", "acv": "I will plant it in the mountain of the height of Israel, and it shall bring forth boughs, and bear fruit, and be a goodly cedar. And all birds of every wing shall dwell under it; they shall dwell in the shade of the branches thereof.", "anderson": "", "haweis": "", "noyes": "Upon a high mountain of Israel will I plant it, and it shall bring forth boughs, and bear fruit, and be a goodly cedar; and under it shall dwell birds of every wing; in the shadow of its branches shall they dwell.", "webster": "In the mountain of the hight of Israel will I plant it: and it shall bring forth boughs, and bear fruit, and be a goodly cedar: and under it shall dwell all fowl of every wing; in the shade of its branches shall they dwell.", "vulgate": "in monte sublimi Israhel plantabo illud et erumpet in germen et faciet fructum et erit in cedrum magnam et habitabunt sub eo omnes volucres universum volatile sub umbra frondium eius nidificabit;", "brenton": "and I will hang it on a lofty mountain of Israel: yea, I will plant it, and it shall put forth shoots, and shall bear fruit, and it shall be a great cedar: and every bird shall rest beneath it, even every fowl shall rest under its shadow: its branches shall be restored."}}, {"v": 24, "ref": "17:24", "o": "וְֽ/יָדְע֞וּ כָּל עֲצֵ֣י הַ/שָּׂדֶ֗ה כִּ֣י אֲנִ֤י יְהוָה֙ הִשְׁפַּ֣לְתִּי עֵ֣ץ גָּבֹ֗הַ הִגְבַּ֨הְתִּי֙ עֵ֣ץ שָׁפָ֔ל הוֹבַ֨שְׁתִּי֙ עֵ֣ץ לָ֔ח וְ/הִפְרַ֖חְתִּי עֵ֣ץ יָבֵ֑שׁ אֲנִ֥י יְהוָ֖ה דִּבַּ֥רְתִּי וְ/עָשִֽׂיתִי", "en": {"kjv": "And all the trees of the field shall know that I the Lord have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish: I the Lord have spoken and have done it.", "web": "All the trees of the field shall know that I, Yahweh, have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish; I, Yahweh, have spoken and have done it.", "bsb": "Then all the trees of the field will know that I am the LORD. I bring the tall tree down and make the low tree tall. I dry up the green tree and make the withered tree flourish. I, the LORD, have spoken, and I have done it.’”", "asv": "And all the trees of the field shall know that I, Jehovah, have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish: I, Jehovah, have spoken and have done it.", "ylt": "And known have all trees of the field That I, Jehovah, have made low the high tree, I have set on high the low tree, I have dried up the moist tree, And I have caused the dry tree to flourish, I, Jehovah, have spoken, and have done it !'", "dra": "And all the trees of the country shall know that I the Lord have brought down the high tree, and exalted the low tree: and have dried up the green tree, and have caused the dry tree to flourish. I the Lord have spoken and have done it.", "bbe": "And it will be clear to all the trees of the field that I the Lord have made low the high tree and made high the low tree, drying up the green tree and making the dry tree full of growth; I the Lord have said it and have done it.", "geneva": "And all the trees of the fielde shall knowe that I the Lord haue brought downe the hie tree, and exalted the lowe tree, that I haue dried vp the greene tree, and made the drie tree to florish: I the Lord haue spoken it, and haue done it.", "wycliffe": "And alle trees of the cuntrei schulen wite, that Y am the Lord; Y made low the hiy tre, and Y enhaunside the low tre, and Y made drie the greene tree, and Y made the drie tree to brynge forth boowis; Y the Lord haue spoke, and Y haue do.", "rotherham": "So shall all the trees of the field know that I Yahweh Have laid low the high tree Have exalted the low tree, Have dried up the moist tree, And have caused to flourish the tree, that was dry,— I, Yahweh, have spoken, and performed.", "darby": "And all the trees of the field shall know that I Jehovah have brought down the high tree, have exalted the low tree, have dried up the green tree, and made the dry tree to flourish: I Jehovah have spoken, and will do [it].", "twenty": "", "jps": "And all the trees of the field shall know that I HaShem have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish; I HaShem have spoken and have done it.'", "acv": "And all the trees of the field shall know that I, Jehovah, have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish. I, Jehovah, have spoken and have done it.", "anderson": "", "haweis": "", "noyes": "And all the trees of the field shall know that I, Jehovah, have brought down the high tree, and exalted the low tree; that I have dried up the green tree, and made the dry tree green. I, Jehovah, have spoken, and will do it.", "webster": "And all the trees of the field shall know that I the LORD have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish: I the LORD have spoken and have done [it].", "vulgate": "et scient omnia ligna regionis quia ego Dominus humiliavi lignum sublime et exaltavi lignum humile et siccavi lignum viride et frondere feci lignum aridum ego Dominus locutus sum et feci;", "brenton": "And all the trees of the field shall know that I am the Lord that bring low the high tree, and exalt the low tree, and wither the green tree, and cause the dry tree to flourish: I the Lord have spoken, and will do it."}}]}, {"c": 18, "verses": [{"v": 1, "ref": "18:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came unto me again, saying,", "web": "Yahweh’s word came to me again, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "The word of Jehovah came unto me again, saying,", "ylt": "`And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying: What is the meaning?", "bbe": "The word of the Lord came to me again, saying,", "geneva": "The worde of the Lord came vnto me againe, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came to me again, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came to me again, saying:", "webster": "The word of the LORD came to me again, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "18:2", "o": "מַה לָּ/כֶ֗ם אַתֶּם֙ מֹֽשְׁלִים֙ אֶת הַ/מָּשָׁ֣ל הַ/זֶּ֔ה עַל אַדְמַ֥ת יִשְׂרָאֵ֖ל לֵ/אמֹ֑ר אָבוֹת֙ יֹ֣אכְלוּ בֹ֔סֶר וְ/שִׁנֵּ֥י הַ/בָּנִ֖ים תִּקְהֶֽינָה", "en": {"kjv": "What mean ye, that ye use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the children’s teeth are set on edge?", "web": "What do you mean, that you use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the children’s teeth are set on edge?", "bsb": "“What do you people mean by quoting this proverb about the land of Israel: ‘The fathers have eaten sour grapes, and the teeth of the children are set on edge’?", "asv": "What mean ye, that ye use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the children’s teeth are set on edge?", "ylt": "`What--to you, ye--using this simile Concerning the ground of Israel, saying: Fathers do eat unripe fruit, And the sons' teeth are blunted?", "dra": "That you use among you this parable as a proverb in the land of Israel, saying: The fathers have eaten sour grapes, and the teeth of the children are set on edge.", "bbe": "Why do you make use of this saying about the land of Israel, The fathers have been tasting bitter grapes and the children's teeth are on edge?", "geneva": "What meane ye that ye speake this prouerbe, concerning the land of Israel, saying, The fathers haue eaten sowre grapes, and the childrens teeth are set on edge?", "wycliffe": "and he seide, What is it, that ye turnen a parable among you in to this prouerbe, in the lond of Israel, and seien, Fadris eeten a bittir grape, and the teeth of sones ben an egge, ether astonyed?", "rotherham": "What occasion have ye, to be using this proverb, concerning the soil of Israel, saying, —Fathers eat sour grapes, And the children’s teeth are blunted?", "darby": "What mean ye, ye who use this proverb of the land of Israel, saying, [The] fathers eat sour grapes, and the children's teeth are set on edge?", "twenty": "", "jps": "'What mean ye, that ye use this proverb in the land of Israel, saying: The fathers have eaten sour grapes, and the children's teeth are set on edge?", "acv": "What do ye mean, that ye use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the son's teeth are set on edge?", "anderson": "", "haweis": "", "noyes": "What mean ye, that ye use this proverb concerning the land of Israel, saying, \"The fathers have eaten sour grapes, and the children’s teeth are set on edge\"?", "webster": "What mean ye, that ye use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the children's teeth are set on edge?", "vulgate": "quid est quod inter vos parabolam vertitis in proverbium istud in terra Israhel dicentes patres comederunt uvam acerbam et dentes filiorum obstupescunt;", "brenton": "Son of man, what mean ye by this parable among the children of Israel, saying, The fathers have eaten unripe grapes, and the children's teeth have been set on edge?"}}, {"v": 3, "ref": "18:3", "o": "חַי אָ֕נִי נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה אִם יִֽהְיֶ֨ה לָ/כֶ֜ם ע֗וֹד מְשֹׁ֛ל הַ/מָּשָׁ֥ל הַ/זֶּ֖ה בְּ/יִשְׂרָאֵֽל", "en": {"kjv": "As I live, saith the Lord God, ye shall not have occasion any more to use this proverb in Israel.", "web": "As I live, says the Lord Yahweh, you shall not use this proverb any more in Israel.", "bsb": "As surely as I live, declares the Lord GOD, you will no longer quote this proverb in Israel.", "asv": "As I live, saith the Lord Jehovah, ye shall not have occasion any more to use this proverb in Israel.", "ylt": "I live--an affirmation of the Lord Jehovah, Ye have no more the use of this simile in Israel.", "dra": "As I live, saith the Lord God, this parable shall be no more to you a proverb in Israel.", "bbe": "By my life, says the Lord, you will no longer have this saying in Israel.", "geneva": "As I liue, sayth the Lord God, ye shall vse this prouerbe no more in Israel.", "wycliffe": "Y lyue, seith the Lord God, this parable schal no more be in to a prouerbe to you in Israel.", "rotherham": "As I live, Declareth My Lord, Yahweh, Surely ye shall have occasion no longer to use this proverb, in Israel.", "darby": "[As] I live, saith the Lord Jehovah, ye shall not have any more to use this proverb in Israel.", "twenty": "", "jps": "As I live, saith the L-rd GOD, ye shall not have occasion any more to use this proverb in Israel.", "acv": "As I live, says the lord Jehovah, ye shall not have occasion any more to use this proverb in Israel.", "anderson": "", "haweis": "", "noyes": "As I live, saith the Lord Jehovah, ye shall not have occasion any more to use this proverb in Israel.", "webster": "[As] I live, saith the Lord GOD, ye shall not have [occasion] any more to use this proverb in Israel.", "vulgate": "vivo ego dicit Dominus Deus si erit vobis ultra parabola haec in proverbium in Israhel;", "brenton": "As I live, saith the Lord, surely this parable shall no more be spoken in Israel."}}, {"v": 4, "ref": "18:4", "o": "הֵ֤ן כָּל הַ/נְּפָשׁוֹת֙ לִ֣/י הֵ֔נָּה כְּ/נֶ֧פֶשׁ הָ/אָ֛ב וּ/כְ/נֶ֥פֶשׁ הַ/בֵּ֖ן לִ/י הֵ֑נָּה הַ/נֶּ֥פֶשׁ הַ/חֹטֵ֖את הִ֥יא תָמֽוּת", "en": {"kjv": "Behold, all souls are mine; as the soul of the father, so also the soul of the son is mine: the soul that sinneth, it shall die.", "web": "Behold, all souls are mine; as the soul of the father, so also the soul of the son is mine: the soul who sins, he shall die.", "bsb": "Behold, every soul belongs to Me; both father and son are Mine. The soul who sins is the one who will die.", "asv": "Behold, all souls are mine; as the soul of the father, so also the soul of the son is mine: the soul that sinneth, it shall die.", "ylt": "Lo, all the souls are Mine, As the soul of the father, So also the soul of the son--they are Mine, The soul that is sinning--it doth die.", "dra": "Behold all souls are mine: as the soul of the father, so also the soul of the son is mine: the soul that sinneth, the same shall die.", "bbe": "See, all souls are mine; as the soul of the father, so the soul of the son is mine: death will be the fate of the sinner's soul.", "geneva": "Beholde, all soules are mine, both the soule of the father, and also the soule of the sonne are mine: the soule that sinneth, it shall die.", "wycliffe": "Lo! alle soulis ben myne; as the soule of the fadir, so and the soule of the sone is myn. Thilke soule that doith synne, schal die.", "rotherham": "Lo! as for all persons, mine they are, As the person of the father, so also the person of the son, mine they are,—The person that sinneth, the same shall die.", "darby": "Behold, all the souls are mine; as the soul of the father, so also the soul of the son is mine: the soul that sinneth, it shall die.", "twenty": "", "jps": "Behold, all souls are Mine; as the soul of the father, so also the soul of the son is Mine; the soul that sinneth, it shall die.", "acv": "Behold, all souls are mine, as the soul of the father, so also the soul of the son is mine. The soul that sins, it shall die.", "anderson": "", "haweis": "", "noyes": "Behold, all souls are mine; as the soul of the father, so also the soul of the son, is mine; the soul that sinneth, it shall die.", "webster": "Behold, all souls are mine; as the soul of the father, so also the soul of the son is mine: the soul that sinneth, it shall die.", "vulgate": "ecce omnes animae meae sunt ut anima patris ita et anima filii mea est anima quae peccaverit ipsa morietur;", "brenton": "For all souls are mine; as the soul of the father, so also the soul of the son, they are mine: the soul that sins, it shall die."}}, {"v": 5, "ref": "18:5", "o": "וְ/אִ֖ישׁ כִּי יִהְיֶ֣ה צַדִּ֑יק וְ/עָשָׂ֥ה מִשְׁפָּ֖ט וּ/צְדָקָֽה", "en": {"kjv": "But if a man be just, and do that which is lawful and right,", "web": "But if a man is just, and does that which is lawful and right,", "bsb": "Now suppose a man is righteous and does what is just and right:", "asv": "But if a man be just, and do that which is lawful and right,", "ylt": "And a man, when he is righteous, And hath done judgment and righteousness,", "dra": "And if a man be just, and do judgment and justice,", "bbe": "But if a man is upright, living rightly and doing righteousness,", "geneva": "But if a man be iust, and doe that which is lawfull, and right,", "wycliffe": "And if a man is iust, and doith doom and riytfulnesse,", "rotherham": "But when, any man, shall be righteous, and do justice and righteousness:", "darby": "And if a man be righteous, and do judgment and justice:", "twenty": "", "jps": "But if a man be just, and do that which is lawful and right,", "acv": "But if a man be just, and does that which is lawful and right,", "anderson": "", "haweis": "", "noyes": "But if a man be just, and do that which is lawful and right;", "webster": "But if a man is just, and doeth that which is lawful and right,", "vulgate": "et vir si fuerit iustus et fecerit iudicium et iustitiam;", "brenton": "But the man who shall be just, who executes judgment and righteousness,"}}, {"v": 6, "ref": "18:6", "o": "אֶל הֶֽ/הָרִים֙ לֹ֣א אָכָ֔ל וְ/עֵינָי/ו֙ לֹ֣א נָשָׂ֔א אֶל גִּלּוּלֵ֖י בֵּ֣ית יִשְׂרָאֵ֑ל וְ/אֶת אֵ֤שֶׁת רֵעֵ֨/הוּ֙ לֹ֣א טִמֵּ֔א וְ/אֶל אִשָּׁ֥ה נִדָּ֖ה לֹ֥א יִקְרָֽב", "en": {"kjv": "And hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbour’s wife, neither hath come near to a menstruous woman,", "web": "and has not eaten on the mountains, neither has lifted up his eyes to the idols of the house of Israel, neither has defiled his neighbor’s wife, neither has come near to a woman in her impurity,", "bsb": "He does not eat at the mountain or look to the idols of the house of Israel. He does not defile his neighbor’s wife or approach a woman during her period.", "asv": "and hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbor’s wife, neither hath come near to a woman in her impurity,", "ylt": "On the mountains he hath not eaten, And his eyes he hath not lifted up Unto idols of the house of Israel, And the wife of his neighbour defiled not, And to a separated woman cometh not near,", "dra": "And hath not eaten upon the mountains, nor lifted up his eyes to the idols of the house of Israel: and hath not defiled his neighbour's wife, nor come near to a menstruous woman:", "bbe": "And has not taken flesh with the blood for food, or given worship to the images of the children of Israel; if he has not had connection with his neighbour's wife, or come near to a woman at the time when she is unclean;", "geneva": "And hath not eaten vpon the mountaines, neither hath lift vp his eyes to the idoles of the house of Israel, neither hath defiled his neighbours wife, neither hath lyen with a menstruous woman,", "wycliffe": "etith not in hillis, and reisith not hise iyen to the idols of the hous of Israel; and defoulith not the wijf of his neiybore, and neiyeth not to a womman defoulid with vncleene blood;", "rotherham": "Upon the mountains, hath not eaten, And his eyes, hath not lifted up unto the manufactured gods of the house of Israel, And the wife of his neighbour, hath not defiled, And unto a woman during her removal, hath not approached;", "darby": "— he hath not eaten upon the mountains, nor lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbour's wife, nor come near to a woman in her separation,", "twenty": "", "jps": "and hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbour's wife, neither hath come near to a woman in her impurity;", "acv": "and has not eaten upon the mountains, nor has lifted up his eyes to the idols of the house of Israel, nor has defiled his neighbor's wife, nor has come near to a woman in her impurity,", "anderson": "", "haweis": "", "noyes": "if he eat not upon the mountains, and lift not up his eyes to the idols of the house of Israel, and defile not his neighbor’s wife, and come not near a woman during her uncleanness;", "webster": "[And] hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbor's wife, neither hath come near to a polluted woman,", "vulgate": "in montibus non comederit et oculos suos non levaverit ad idola domus Israhel et uxorem proximi sui non violaverit et ad mulierem menstruatam non accesserit;", "brenton": "who shall not eat upon the mountains, and shall not at all lift up his eyes to the devices of the house of Israel, and shall not defile his neighbor's wife, and shall not draw nigh to her that is removed,"}}, {"v": 7, "ref": "18:7", "o": "וְ/אִישׁ֙ לֹ֣א יוֹנֶ֔ה חֲבֹלָת֥/וֹ חוֹב֙ יָשִׁ֔יב גְּזֵלָ֖ה לֹ֣א יִגְזֹ֑ל לַחְמ/וֹ֙ לְ/רָעֵ֣ב יִתֵּ֔ן וְ/עֵירֹ֖ם יְכַסֶּה בָּֽגֶד", "en": {"kjv": "And hath not oppressed any, but hath restored to the debtor his pledge, hath spoiled none by violence, hath given his bread to the hungry, and hath covered the naked with a garment;", "web": "and has not wronged any, but has restored to the debtor his pledge, has taken nothing by robbery, has given his bread to the hungry, and has covered the naked with a garment;", "bsb": "He does not oppress another, but restores the pledge to the debtor. He does not commit robbery, but gives his bread to the hungry and covers the naked with clothing.", "asv": "and hath not wronged any, but hath restored to the debtor his pledge, hath taken nought by robbery, hath given his bread to the hungry, and hath covered the naked with a garment;", "ylt": "A man--he doth not oppress, His pledge to the debtor he doth return, Plunder he doth not take away, His bread to the hungry he doth give, And the naked doth cover with a garment,", "dra": "And hath not wronged any man: but hath restored the pledge to the debtor, hath taken nothing away by violence: hath given his bread to the hungry, and hath covered the naked with a garment:", "bbe": "And has done no wrong to any, but has given back to the debtor what is his, and has taken no one's goods by force, and has given food to him who was in need of it, and clothing to him who was without it;", "geneva": "Neither hath oppressed any, but hath restored the pledge to his dettour: he that hath spoyled none by violence, but hath giuen his bread to the hungry, and hath couered the naked with a garment,", "wycliffe": "and makith not a man sori, yeldith the wed to the dettour, rauyschith no thing bi violence, yyueth his breed to the hungri, and hilith a nakid man with a cloth;", "rotherham": "And no man, hath treated with violence, But his debt-pledge, hath restored. Plunder, hath not seized,— His bread—to the famished, hath given, And the naked, hath covered with clothing;", "darby": "and hath not oppressed any; he hath restored to the debtor his pledge, hath not exercised robbery, hath given his bread to the hungry, and covered the naked with a garment;", "twenty": "", "jps": "and hath not wronged any, but hath restored his pledge for a debt, hath taken nought by robbery, hath given his bread to the hungry, and hath covered the naked with a garment;", "acv": "and has not wronged any man, but has restored to the debtor his pledge, has taken nothing by robbery, has given his bread to a hungry man, and has covered a naked man with a garment,", "anderson": "", "haweis": "", "noyes": "if he oppress not any, if he restore to the debtor his pledge, spoil none by violence, give his bread to the hungry, and cover the naked with a garment;", "webster": "And hath not oppressed any, [but] hath restored to the debtor his pledge, hath stripped none by violence, hath given his bread to the hungry, and hath covered the naked with a garment:", "vulgate": "et hominem non contristaverit pignus debitori reddiderit per vim nihil rapuerit panem suum esurienti dederit et nudum operuerit vestimento;", "brenton": "and shall not oppress any man, but shall return the pledge of the debtor, and shall be guilty of no plunder, shall give his bread to the hungry, and clothe the naked;"}}, {"v": 8, "ref": "18:8", "o": "בַּ/נֶּ֣שֶׁךְ לֹֽא יִתֵּ֗ן וְ/תַרְבִּית֙ לֹ֣א יִקָּ֔ח מֵ/עָ֖וֶל יָשִׁ֣יב יָד֑/וֹ מִשְׁפַּ֤ט אֱמֶת֙ יַֽעֲשֶׂ֔ה בֵּ֥ין אִ֖ישׁ לְ/אִֽישׁ", "en": {"kjv": "He that hath not given forth upon usury, neither hath taken any increase, that hath withdrawn his hand from iniquity, hath executed true judgment between man and man,", "web": "he who has not lent on interest, neither has taken any increase, who has withdrawn his hand from iniquity, has executed true justice between man and man,", "bsb": "He does not engage in usury or take excess interest, but he withholds his hand from iniquity and executes true justice between men.", "asv": "he that hath not given forth upon interest, neither hath taken any increase, that hath withdrawn his hand from iniquity, hath executed true justice between man and man,", "ylt": "In usury he doth not give, and increase taketh not, From perversity he turneth back his hand, True judgment he doth between man and man.", "dra": "Hath not lent upon usury, nor taken any increase: hath withdrawn his hand from iniquity, and hath executed true judgment between man and man:", "bbe": "And has not given his money out at interest or taken great profits, and, turning his hand from evil-doing, has kept faith between man and man,", "geneva": "And hath not giuen foorth vpon vsurie, neither hath taken any increase, but hath withdrawen his hand from iniquitie, and hath executed true iudgement betweene man and man,", "wycliffe": "leeneth not to vsure, and takith not more; turneth awei his hond fro wickidnesse, and makith trewe dom bitwixe man and man;", "rotherham": "Upon interest, hath not put out his money. And increase, hath not accepted, From dishonesty, hath turned back his hand,— Justice in truth, hath done, between man and man;", "darby": "he hath not given forth upon usury, nor taken increase; he hath withdrawn his hand from unrighteousness, hath executed true judgment between man and man,", "twenty": "", "jps": "he that hath not given forth upon interest, neither hath taken any increase, that hath withdrawn his hand from iniquity, hath executed true justice between man and man,", "acv": "he who has not given forth upon interest, nor has taken any increase, who has withdrawn his hand from iniquity, has executed true justice between man and man,", "anderson": "", "haweis": "", "noyes": "if he give not forth upon usury, and take not increase; if he withdraw his hand from iniquity, and give true judgment between man and man;", "webster": "He [that] hath not given forth upon interest, neither hath taken any increase, [that] hath withdrawn his hand from iniquity, hath executed true judgment between man and man,", "vulgate": "ad usuram non commodaverit et amplius non acceperit ab iniquitate averterit manum suam iudicium verum fecerit inter virum et virum;", "brenton": "and shall not lend his money upon usury, and shall not receive usurious increase, and shall turn back his hand from injustice, shall execute righteous judgment between a man and his neighbor,"}}, {"v": 9, "ref": "18:9", "o": "בְּ/חֻקּוֹתַ֧/י יְהַלֵּ֛ךְ וּ/מִשְׁפָּטַ֥/י שָׁמַ֖ר לַ/עֲשׂ֣וֹת אֱמֶ֑ת צַדִּ֥יק הוּא֙ חָיֹ֣ה יִֽחְיֶ֔ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Hath walked in my statutes, and hath kept my judgments, to deal truly; he is just, he shall surely live, saith the Lord God.", "web": "has walked in my statutes, and has kept my ordinances, to deal truly; he is just, he shall surely live, says the Lord Yahweh.", "bsb": "He follows My statutes and faithfully keeps My ordinances. That man is righteous; surely he will live, declares the Lord GOD.", "asv": "hath walked in my statutes, and hath kept mine ordinances, to deal truly; he is just, he shall surely live, saith the Lord Jehovah.", "ylt": "In My statutes he doth walk, And My judgments he hath kept--to deal truly, Righteous is he, he surely liveth, An affirmation of the Lord Jehovah.", "dra": "Hath walked in my commandments, and kept my judgments, to do truth: he is just, he shall surely live, saith the Lord God.", "bbe": "And has been guided by my rules and has kept my laws and done them: he is upright, life will certainly be his, says the Lord.", "geneva": "And hath walked in my statutes, and hath kept my iudgements to deale truely, he is iust, he shall surely liue, sayth the Lord God.", "wycliffe": "and goith in my comaundementis, and kepith my domes, that he do treuthe; this is a iust man, he schal lyue in lijf, seith the Lord God.", "rotherham": "In my statutes, hath walked. And my regulations, hath observed to do them in truth, Righteous, he is, He shall surely live, Declareth My Lord. Yahweh.", "darby": "hath walked in my statutes, and kept mine ordinances, to deal faithfully: he is righteous, he shall certainly live, saith the Lord Jehovah.", "twenty": "", "jps": "hath walked in My statutes, and hath kept Mine ordinances, to deal truly; he is just, he shall surely live, saith the L-rd GOD.", "acv": "has walked in my statutes, and has kept my ordinances, to deal truly, he is just. He shall surely live, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "if he walk in my statutes and keep my commandments, to deal uprightly,—he is just; he shall surely live, saith the Lord Jehovah.", "webster": "Hath walked in my statutes, and hath kept my judgments, to deal truly; he [is] just, he shall surely live, saith the Lord GOD.", "vulgate": "in praeceptis meis ambulaverit et iudicia mea custodierit ut faciat veritatem hic iustus est vita vivet ait Dominus Deus;", "brenton": "and has walked in my commandments and kept mine ordinances, to do them; he is righteous, he shall surely live, saith the Lord."}}, {"v": 10, "ref": "18:10", "o": "וְ/הוֹלִ֥יד בֵּן פָּרִ֖יץ שֹׁפֵ֣ךְ דָּ֑ם וְ/עָ֣שָׂה אָ֔ח מֵ/אַחַ֖ד מֵ/אֵֽלֶּה", "en": {"kjv": "If he beget a son that is a robber, a shedder of blood, and that doeth the like to any one of these things,", "web": "If he fathers a son who is a robber who sheds blood, and who does any one of these things,", "bsb": "Now suppose that man has a violent son, who sheds blood or does any of these things,", "asv": "If he beget a son that is a robber, a shedder of blood, and that doeth any one of these things,", "ylt": "And--he hath begotten a son, A burglar--a shedder of blood, And he hath made a brother of one of these,", "dra": "And if he beget a son that is a robber, a shedder of blood, and that hath done some one of these things:", "bbe": "If he has a son who is a thief, a taker of life, who does any of these things,", "geneva": "If he beget a sonne, that is a thiefe, or a sheader of blood, if he do any one of these things,", "wycliffe": "That if he gendrith a sone, a theef, shedinge out blood,", "rotherham": "But he hath begotten a son Who is a violent man A shedder of blood,- Who doeth the like of any of these things;", "darby": "And if he have begotten a son that is violent, a shedder of blood, and that doeth only one of any of these [things],", "twenty": "", "jps": "If he beget a son that is a robber, a shedder of blood, and that doeth to a brother any of these things,", "acv": "If he begets a son who is a robber, a shedder of blood, and who does any one of these things,", "anderson": "", "haweis": "", "noyes": "But if he have a son that is a robber, a shedder of blood, and that doeth to his brother any of these things,", "webster": "If he begetteth a son [that is] a robber, a shedder of blood, and [that] doeth the like to [any] one of these [things],", "vulgate": "quod si genuerit filium latronem effundentem sanguinem et fecerit unum de istis;", "brenton": "And if he beget a mischievous son, shedding blood and committing sins,"}}, {"v": 11, "ref": "18:11", "o": "וְ/ה֕וּא אֶת כָּל אֵ֖לֶּה לֹ֣א עָשָׂ֑ה כִּ֣י גַ֤ם אֶל הֶֽ/הָרִים֙ אָכַ֔ל וְ/אֶת אֵ֥שֶׁת רֵעֵ֖/הוּ טִמֵּֽא", "en": {"kjv": "And that doeth not any of those duties, but even hath eaten upon the mountains, and defiled his neighbour’s wife,", "web": "or who does not do any of those things, but even has eaten on the mountains, and defiled his neighbor’s wife,", "bsb": "though the father has done none of them: Indeed, the son eats at the mountain and defiles his neighbor’s wife.", "asv": "and that doeth not any of those duties, but even hath eaten upon the mountains, and defiled his neighbor’s wife,", "ylt": "And he all those hath not done, For even on the mountains he hath eaten, And the wife of his neighbour he hath defiled,", "dra": "Though he doth not all these things, but that eateth upon the mountains, and that defileth his neighbour's wife:", "bbe": "Who has taken flesh with the blood as food, and has had connection with his neighbour's wife,", "geneva": "Though he doe not all these things, but either hath eaten vpon the mountaines, or defiled his neighbours wife,", "wycliffe": "and doith oon of thes thingis, and sotheli not doing alle these thingis, but etinge in hillis, and defoulynge the wijf of his neiybore;", "rotherham": "Whereas he, none of those other things, doeth, For indeed upon the mountains, he hath eaten, And the wife of his neighbour, hath defiled;", "darby": "and that doeth not any of those [duties], but also hath eaten upon the mountains, and defiled his neighbour's wife,", "twenty": "", "jps": "whereas he himself had not done any of these things, for he hath even eaten upon the mountains, and defiled his neighbour's wife,", "acv": "and who does not do any of those duties, but has even eaten upon the mountains, and defiled his neighbor's wife,", "anderson": "", "haweis": "", "noyes": "and doeth not all those duties, but eateth upon the mountains, and defileth his neighbor’s wife,", "webster": "And that doeth not any of those [duties], but even hath eaten upon the mountains, and defiled his neighbor's wife,", "vulgate": "et haec quidem omnia non facientem sed in montibus comedentem et uxorem proximi sui polluentem;", "brenton": "who has not walked in the way of his righteous father, but has even eaten upon the mountains, and has defiled his neighbor's wife,"}}, {"v": 12, "ref": "18:12", "o": "עָנִ֤י וְ/אֶבְיוֹן֙ הוֹנָ֔ה גְּזֵל֣וֹת גָּזָ֔ל חֲבֹ֖ל לֹ֣א יָשִׁ֑יב וְ/אֶל הַ/גִּלּוּלִים֙ נָשָׂ֣א עֵינָ֔י/ו תּוֹעֵבָ֖ה עָשָֽׂה", "en": {"kjv": "Hath oppressed the poor and needy, hath spoiled by violence, hath not restored the pledge, and hath lifted up his eyes to the idols, hath committed abomination,", "web": "has wronged the poor and needy, has taken by robbery, has not restored the pledge, and has lifted up his eyes to the idols, has committed abomination,", "bsb": "He oppresses the poor and needy; he commits robbery and does not restore a pledge. He lifts his eyes to idols; he commits abominations.", "asv": "hath wronged the poor and needy, hath taken by robbery, hath not restored the pledge, and hath lifted up his eyes to the idols, hath committed abomination,", "ylt": "The afflicted and needy he hath oppressed, Plunder he hath taken violently away, A pledge he doth not return, And unto the idols he hath lifted up his eyes, Abomination he hath done!", "dra": "That grieveth the needy and the poor, that taketh away by violence, that restoreth not the pledge, and that lifteth up his eyes to idols, that comitteth abomination:", "bbe": "Has done wrong to the poor and to him who is in need, and taken property by force, and has not given back to one in his debt what is his, and has given worship to images and has done disgusting things,", "geneva": "Or hath oppressed the poore and needy, or hath spoyled by violence, or hath not restored the pledge, or hath lift vp his eyes vnto the idoles, or hath committed abomination,", "wycliffe": "makynge soreuful a nedy man and pore, rauyschynge raueyns, not yeldinge a wed, reisynge hise iyen to idols, doynge abhomynacioun; yiuynge to vsure, and takynge more;", "rotherham": "The oppressed and the needy, hath treated with violence, Hath ruthlessly plundered, The pledge, hath not restored, But unto the manufactured gods, hath lifted up his eyes, Abomination, hath wrought;", "darby": "hath oppressed the poor and needy, exercised robbery, hath not restored the pledge, and hath lifted up his eyes to the idols, committed abomination,", "twenty": "", "jps": "hath wronged the poor and needy, hath taken by robbery, hath not restored the pledge, and hath lifted up his eyes to the idols, hath committed abomination,", "acv": "has wronged the poor and needy man, has taken by robbery, has not restored the pledge, and has lifted up his eyes to the idols, has committed abomination,", "anderson": "", "haweis": "", "noyes": "oppresseth the poor and needy, spoileth by violence, restoreth not the pledge, lifteth up his eyes to idols, and committeth abomination,", "webster": "Hath oppressed the poor and needy, hath stripped by violence, hath not restored the pledge, and hath lifted up his eyes to the idols, hath committed abomination.", "vulgate": "egenum et pauperem contristantem rapientem rapinas pignus non reddentem et ad idola levantem oculos suos abominationem facientem;", "brenton": "and has oppressed the poor and needy, and has committed robbery, and not restored a pledge, and has set his eyes upon idols, has wrought iniquities,"}}, {"v": 13, "ref": "18:13", "o": "בַּ/נֶּ֧שֶׁךְ נָתַ֛ן וְ/תַרְבִּ֥ית לָקַ֖ח וָ/חָ֑י לֹ֣א יִֽחְיֶ֗ה אֵ֣ת כָּל הַ/תּוֹעֵב֤וֹת הָ/אֵ֨לֶּה֙ עָשָׂ֔ה מ֣וֹת יוּמָ֔ת דָּמָ֖י/ו בּ֥/וֹ יִהְיֶֽה", "en": {"kjv": "Hath given forth upon usury, and hath taken increase: shall he then live? he shall not live: he hath done all these abominations; he shall surely die; his blood shall be upon him.", "web": "has lent on interest, and has taken increase; shall he then live? he shall not live: he has done all these abominations; he shall surely die; his blood shall be on him.", "bsb": "He engages in usury and takes excess interest. Will this son live? He will not! Since he has committed all these abominations, he will surely die; his blood will be on his own head.", "asv": "hath given forth upon interest, and hath taken increase; shall he then live? he shall not live: he hath done all these abominations; he shall surely die; his blood shall be upon him.", "ylt": "In usury he hath given, and increase taken, And he liveth: he doth not live, All these abominations he hath done, He doth surely die, his blood is on him.", "dra": "That giveth upon usury, and that taketh an increase: shall such a one live? he shall not live. Seeing he hath done all these detestable things, he shall surely die, his blood shall be upon him.", "bbe": "And has given out his money at interest and taken great profits: he will certainly not go on living: he has done all these disgusting things: death will certainly be his fate; his blood will be on him.", "geneva": "Or hath giuen forth vpon vsurie, or hath taken increase, shall he liue? he shall not liue: seeing he hath done all these abominations, he shall die the death, and his blood shall be vpon him.", "wycliffe": "whether he schal lyue? he schal not lyue; whanne he hath do alle these abhomynable thingis, he schal die bi deth, his blood schal be in hym.", "rotherham": "Upon interest, hath put out. And increase, hath accepted—, And shall he live? He shall not live All these abominations, he hath done, He shall surely be put to death, His blood, upon himself, shall be.", "darby": "given forth upon usury, and taken increase; shall he then live? He shall not live: he hath done all these abominations; he shall certainly die; his blood shall be upon him.", "twenty": "", "jps": "hath given forth upon interest, and hath taken increase; shall he then live? he shall not live--he hath done all these abominations; he shall surely be put to death, his blood shall be upon him.", "acv": "has given forth upon interest, and has taken increase, shall he then live? He shall not live. He has done all these abominations. He shall surely die. His blood shall be upon him.", "anderson": "", "haweis": "", "noyes": "giveth forth upon usury, and taketh increase, shall he live? No! he shall not live. He hath done all these abominations; he shall surely die; his blood shall be upon him.", "webster": "Hath given forth upon interest, and hath taken increase: shall he then live? he shall not live: he hath done all these abominations; he shall surely die; his blood shall be upon him.", "vulgate": "ad usuram dantem et amplius accipientem numquid vivet non vivet cum universa detestanda haec fecerit morte morietur sanguis eius in ipso erit;", "brenton": "has lent upon usury, and taken usurious increase; he shall by no means live: he has wrought all these iniquities; he shall surely die; his blood shall be upon him."}}, {"v": 14, "ref": "18:14", "o": "וְ/הִנֵּה֙ הוֹלִ֣יד בֵּ֔ן וַ/יַּ֕רְא אֶת כָּל חַטֹּ֥את אָבִ֖י/ו אֲשֶׁ֣ר עָשָׂ֑ה וַ/יִּרְאֶ֕ה וְ/לֹ֥א יַעֲשֶׂ֖ה כָּ/הֵֽן", "en": {"kjv": "Now, lo, if he beget a son, that seeth all his father’s sins which he hath done, and considereth, and doeth not such like,", "web": "Now, behold, if he fathers a son, who sees all his father’s sins, which he has done, and fears, and does not such like;", "bsb": "Now suppose this son has a son who sees all the sins his father has committed, considers them, and does not do likewise:", "asv": "Now, lo, if he beget a son, that seeth all his father’s sins, which he hath done, and feareth, and doeth not such like;", "ylt": "And--lo, he hath begotten a son, And he seeth all the sins of his father, That he hath done, and he feareth, And doth not do like them,", "dra": "But if he beget a son, who, seeing all his father's sins, which he hath done, is afraid, and shall not do the like to them:", "bbe": "Now if he has a son who sees all his father's sins which he has done, and in fear does not do the same:", "geneva": "But if he beget a sonne, that seeth all his fathers sinnes, which he hath done, and feareth, neither doeth such like,", "wycliffe": "That if he gendrith a sone, which seeth alle the synnes of his fadir, whiche he dide, and dredith, and doith noon lijk tho;", "rotherham": "But lo! he hath begotten a son, Who hath considered all the sins of his father which he hath done,- Yea he hath considered and not done like them:", "darby": "But lo, if he have begotten a son that seeth all his father's sins which he hath done, and considereth, and doeth not such like:", "twenty": "", "jps": "Now, lo, if he beget a son, that seeth all his father's sins, which he hath done, and considereth, and doeth not such like,", "acv": "Now, lo, if he begets a son, who sees all his father's sins, which he has done, and fears, and does not do such like,", "anderson": "", "haweis": "", "noyes": "Yet lo, if he have a son that seeth all the sins which his father committed, that seeth them and doeth not such like,", "webster": "Now lo, [if] he begetteth a son, that seeth all his father's sins which he hath done, and considereth, and doeth not such like,", "vulgate": "quod si genuerit filium qui videns omnia peccata patris sui quae fecit timuerit et non fecerit simile eis;", "brenton": "And if he beget a son, and the son see all his father's sins which he has wrought, and fear, and not do according to them,"}}, {"v": 15, "ref": "18:15", "o": "עַל הֶֽ/הָרִים֙ לֹ֣א אָכָ֔ל וְ/עֵינָי/ו֙ לֹ֣א נָשָׂ֔א אֶל גִּלּוּלֵ֖י בֵּ֣ית יִשְׂרָאֵ֑ל אֶת אֵ֥שֶׁת רֵעֵ֖/הוּ לֹ֥א טִמֵּֽא", "en": {"kjv": "That hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, hath not defiled his neighbour’s wife,", "web": "who has not eaten on the mountains, neither has lifted up his eyes to the idols of the house of Israel, has not defiled his neighbor’s wife,", "bsb": "He does not eat at the mountain or look to the idols of the house of Israel. He does not defile his neighbor’s wife.", "asv": "that hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, hath not defiled his neighbor’s wife,", "ylt": "On the mountains he hath not eaten, And his eyes he hath not lifted up Unto idols of the house of Israel, The wife of his neighbour he hath not defiled,", "dra": "That hath not eaten upon the mountains, nor lifted up his eyes to the idols of the house of Israel, and hath not defiled his neighbour's wife:", "bbe": "Who has not taken the flesh with the blood for food, or given worship to the images of the children of Israel, and has not had connection with his neighbour's wife,", "geneva": "That hath not eaten vpon the mountaines, neither hath lift vp his eyes to the idols of ye house of Israel, nor hath defiled his neighbours wife,", "wycliffe": "etith not on hillis, and reisith not hise iyen to the idols of the hous of Israel; and defoulith not the wijf of his neiybore,", "rotherham": "Upon the mountains, hath not eaten, And his eyes, hath not lifted up unto the manufactured gods of the house of Israel, The wife of his neighbour, hath not defiled;", "darby": "— he hath not eaten upon the mountains, nor lifted up his eyes to the idols of the house of Israel; he hath not defiled his neighbour's wife,", "twenty": "", "jps": "that hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, hath not defiled his neighbour's wife,", "acv": "who has not eaten upon the mountains, nor has lifted up his eyes to the idols of the house of Israel, has not defiled his neighbor's wife,", "anderson": "", "haweis": "", "noyes": "that eateth not upon the mountains, nor lifteth up his eyes to the idols of the house of Israel, nor defileth his neighbor’s wife,", "webster": "[That] hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, hath not defiled his neighbor's wife,", "vulgate": "super montes non comederit et oculos suos non levaverit ad idola domus Israhel et uxorem proximi sui non violaverit;", "brenton": "and if he has not eaten on the mountains, and has not set his eyes on the devices of the house of Israel, and has not defiled his neighbor's wife,"}}, {"v": 16, "ref": "18:16", "o": "וְ/אִישׁ֙ לֹ֣א הוֹנָ֔ה חֲבֹל֙ לֹ֣א חָבָ֔ל וּ/גְזֵלָ֖ה לֹ֣א גָזָ֑ל לַחְמ/וֹ֙ לְ/רָעֵ֣ב נָתָ֔ן וְ/עֵר֖וֹם כִּסָּה בָֽגֶד", "en": {"kjv": "Neither hath oppressed any, hath not withholden the pledge, neither hath spoiled by violence, but hath given his bread to the hungry, and hath covered the naked with a garment,", "web": "neither has wronged any, has not taken anything to pledge, neither has taken by robbery, but has given his bread to the hungry, and has covered the naked with a garment;", "bsb": "He does not oppress another, or retain a pledge, or commit robbery. He gives his bread to the hungry and covers the naked with clothing.", "asv": "neither hath wronged any, hath not taken aught to pledge, neither hath taken by robbery, but hath given his bread to the hungry, and hath covered the naked with a garment;", "ylt": "A man--he hath not oppressed, A pledge he hath not bound, And plunder he hath not taken away, His bread to the hungry he hath given, And the naked he covered with a garment,", "dra": "And hath not grieved any man, nor withholden the pledge, nor taken away with violence, but hath given his bread to the hungry, and covered the naked with a garment:", "bbe": "Or done wrong to any, or taken anything from one in his debt, or taken goods by force, but has given food to him who was in need of it, and clothing to him who was without it;", "geneva": "Neither hath oppressed any, nor hath withholden the pledge, neither hath spoyled by violence, but hath giuen his bread to the hungry, and hath couered the naked with a garment,", "wycliffe": "and makith not sori a man, witholdith not a wed, and rauyschith not raueyn, yyueth his breed to the hungri, and hilith the nakid with a cloth;", "rotherham": "And no man, hath he treated with violence, Hath by no means withholden the pledge, And plunder, hath not seized,— His bread—to the famished, hath given And the naked, hath covered with clothing;", "darby": "and hath not oppressed any, nor withholden the pledge, neither hath exercised robbery; he hath given his bread to the hungry, and covered the naked with a garment;", "twenty": "", "jps": "neither hath wronged any, hath not taken aught to pledge, neither hath taken by robbery, but hath given his bread to the hungry, and hath covered the naked with a garment,", "acv": "nor has wronged any man, has not taken anything to pledge, nor has taken by robbery, but has given his bread to a hungry man, and has covered a naked man with a garment,", "anderson": "", "haweis": "", "noyes": "nor oppresseth any, nor taketh a pledge, nor spoileth by violence, but giveth his food to the hungry, and covereth the naked with a garment,", "webster": "Neither hath oppressed any, hath not withheld the pledge, neither hath stripped by violence, [but] hath given his bread to the hungry, and hath covered the naked with a garment,", "vulgate": "et virum non contristaverit pignus non retinuerit et rapinam non rapuerit panem suum esurienti dederit et nudum operuerit vestimento;", "brenton": "and has not oppressed a man, and has not retained the pledge, nor committed robbery, has given his bread to the hungry, and has clothed the naked,"}}, {"v": 17, "ref": "18:17", "o": "מֵ/עָנִ֞י הֵשִׁ֣יב יָד֗/וֹ נֶ֤שֶׁךְ וְ/תַרְבִּית֙ לֹ֣א לָקָ֔ח מִשְׁפָּטַ֣/י עָשָׂ֔ה בְּ/חֻקּוֹתַ֖/י הָלָ֑ךְ ה֗וּא לֹ֥א יָמ֛וּת בַּ/עֲוֺ֥ן אָבִ֖י/ו חָיֹ֥ה יִחְיֶֽה", "en": {"kjv": "That hath taken off his hand from the poor, that hath not received usury nor increase, hath executed my judgments, hath walked in my statutes; he shall not die for the iniquity of his father, he shall surely live.", "web": "who has withdrawn his hand from the poor, who has not received interest nor increase, has executed my ordinances, has walked in my statutes; he shall not die for the iniquity of his father, he shall surely live.", "bsb": "He withholds his hand from harming the poor and takes no interest or usury. He keeps My ordinances and follows My statutes. Such a man will not die for his father’s iniquity. He will surely live.", "asv": "that hath withdrawn his hand from the poor, that hath not received interest nor increase, hath executed mine ordinances, hath walked in my statutes; he shall not die for the iniquity of his father, he shall surely live.", "ylt": "From the afflicted he hath turned back his hand, Usury and increase he hath not taken, My judgments he hath done, In My statutes he hath walked, He doth not die for the iniquity of his father, He doth surely live.", "dra": "That hath turned away his hand from injuring the poor, hath not taken usury and increase, but hath executed my judgments, and hath walked in my commandments: this man shall not die for the iniquity of his father, but living he shall live.", "bbe": "Who has kept his hand from evil-doing and has not taken interest or great profits, who has done my orders and been guided by my rules: he will certainly not be put to death for the evil-doing of his father; life will certainly be his.", "geneva": "Neither hath withdrawen his hand from the afflicted, nor receiued vsurie nor increase, but hath executed my iudgements, and hath walked in my statutes, he shall not die in the iniquitie of his father, but he shall surely liue.", "wycliffe": "turneth a wei his hond fro the wrong of a pore man, takith not vsure and ouerhabundaunce, `that is, no thing more than he lente, and doith my domes, and goith in my comaundementis; this sone schal not die in the wickidnesse of his fadir, but he schal lyue in lijf.", "rotherham": "From dishonesty, hath turned back his hand Neither interest nor increase, hath accepted, my regulations, hath executed, In my statutes, hath walked,— He shall not die for the iniquity of his father He shall surely live.", "darby": "he hath withdrawn his hand from the poor, hath not received usury nor increase, hath executed my judgments, [and] walked in my statutes: he shall not die for the iniquity of his father, he shall certainly live.", "twenty": "", "jps": "that hath withdrawn his hand from the poor, that hath not received interest nor increase, hath executed Mine ordinances, hath walked in My statutes; he shall not die for the iniquity of his father, he shall surely live.", "acv": "who has withdrawn his hand from a poor man, who has not received interest nor increase, has executed my ordinances, has walked in my statutes, he shall not die for the iniquity of his father. He shall surely live.", "anderson": "", "haweis": "", "noyes": "keepeth back his hand from the poor, and taketh no usury or increase, keepeth my commandments, and walketh in my statutes, he shall not die for the iniquity of his father; he shall surely live.", "webster": "[That] hath taken off his hand from the poor, [that] hath not received interest nor increase, hath executed my judgments, hath walked in my statutes; he shall not die for the iniquity of his father, he shall surely live.", "vulgate": "a pauperis iniuria averterit manum suam usuram et superabundantiam non acceperit iudicia mea fecerit in praeceptis meis ambulaverit hic non morietur in iniquitate patris sui sed vita vivet;", "brenton": "and has turned back his hand from unrighteousness, has not received interest or usurious increase, has wrought righteousness, and walked in mine ordinances; he shall not die for the iniquities of his father, he shall surely live."}}, {"v": 18, "ref": "18:18", "o": "אָבִ֞י/ו כִּֽי עָ֣שַׁק עֹ֗שֶׁק גָּזַל֙ גֵּ֣זֶל אָ֔ח וַ/אֲשֶׁ֥ר לֹא ט֛וֹב עָשָׂ֖ה בְּ/ת֣וֹךְ עַמָּ֑י/ו וְ/הִנֵּה מֵ֖ת בַּ/עֲוֺנֽ/וֹ", "en": {"kjv": "As for his father, because he cruelly oppressed, spoiled his brother by violence, and did that which is not good among his people, lo, even he shall die in his iniquity.", "web": "As for his father, because he cruelly oppressed, robbed his brother, and did that which is not good among his people, behold, he shall die in his iniquity.", "bsb": "As for his father, he will die for his own iniquity, because he practiced extortion, robbed his brother, and did what was wrong among his people.", "asv": "As for his father, because he cruelly oppressed, robbed his brother, and did that which is not good among his people, behold, he shall die in his iniquity.", "ylt": "His father--because he used oppression, Did violently Plunder a brother, And that which is not good did in the midst of his people, And lo, he is dying in his iniquity.", "dra": "As for his father, because he oppressed and offered violence to his brother, and wrought evil in the midst of his people, behold he is dead in his own iniquity.", "bbe": "As for his father, because he was cruel, took goods by force, and did what is not good among his people, truly, death will overtake him in his evil-doing.", "geneva": "His father, because he cruelly oppressed and spoyled his brother by violence, and hath not done good among his people, loe, euen he dyeth in his iniquitie.", "wycliffe": "For his fadir made fals caleng, and dide violence to his brother, and wrouyte yuel in the myddis of his puple, lo! he is deed in his wickidnesse.", "rotherham": "His father Because he exacted unjust gain Seized plunder of a brother, And that which was not good, had done in the midst of his people Therefore lo! he died, in his iniquity.", "darby": "As for his father, because he practised oppression, exercised robbery upon his brother, and did what was not good among his people, behold, he shall die in his iniquity.", "twenty": "", "jps": "As for his father, because he cruelly oppressed, committed robbery on his brother, and did that which is not good among his people, behold, he dieth for his iniquity.", "acv": "As for his father, because he cruelly oppressed, robbed his brother, and did that which is not good among his people, behold, he shall die in his iniquity.", "anderson": "", "haweis": "", "noyes": "As for his father, because he cruelly oppressed, spoiled his brother by violence, and did that which is not good among his people, lo, he shall die for his iniquity.", "webster": "[As for] his father, because he cruelly oppressed, stripped his brother by violence, and did [that] which [is] not good among his people, lo, even he shall die in his iniquity.", "vulgate": "pater eius quia calumniatus est et vim fecit fratri et malum operatus est in medio populi sui ecce mortuus est in iniquitate sua;", "brenton": "But if his father grievously afflict, or plunder, he has wrought enmity in the midst of my people, and shall die in his iniquity."}}, {"v": 19, "ref": "18:19", "o": "וַ/אֲמַרְתֶּ֕ם מַדֻּ֛עַ לֹא נָשָׂ֥א הַ/בֵּ֖ן בַּ/עֲוֺ֣ן הָ/אָ֑ב וְ/הַ/בֵּ֞ן מִשְׁפָּ֧ט וּ/צְדָקָ֣ה עָשָׂ֗ה אֵ֣ת כָּל חֻקּוֹתַ֥/י שָׁמַ֛ר וַ/יַּעֲשֶׂ֥ה אֹתָ֖/ם חָיֹ֥ה יִחְיֶֽה", "en": {"kjv": "Yet say ye, Why? doth not the son bear the iniquity of the father? When the son hath done that which is lawful and right, and hath kept all my statutes, and hath done them, he shall surely live.", "web": "Yet you say, Why doesn’t the son bear the iniquity of the father? When the son has done that which is lawful and right, and has kept all my statutes, and has done them, he shall surely live.", "bsb": "Yet you may ask, ‘Why shouldn’t the son bear the iniquity of his father?’ Since the son has done what is just and right, carefully observing all My statutes, he will surely live.", "asv": "Yet say ye, Wherefore doth not the son bear the iniquity of the father? When the son hath done that which is lawful and right, and hath kept all my statutes, and hath done them, he shall surely live.", "ylt": "And ye have said, Wherefore hath not the son, Borne of the iniquity of the father? And--the son judgment and righteousness hath done, All My statutes he hath kept, And he doeth them, he surely liveth.", "dra": "And you say: Why hath not the son borne the iniquity of his father? Verily, because the son hath wrought judgment and justice, hath kept all my commandments, and done them, living, he shall live.", "bbe": "But you say, Why does not the son undergo punishment for the evil-doing of the father? When the son has done what is ordered and right, and has kept my rules and done them, life will certainly be his.", "geneva": "Yet say ye, Wherefore shall not the sonne beare the iniquitie of the father? because ye sonne hath executed iudgement and iustice, and hath kept all my statutes, and done them, he shall surely liue,", "wycliffe": "And ye seien, Whi berith not the sone the wickidnesse of the fadir? That is to seie, for the sone wrouyte doom and riytfulnesse, he kepte alle my comaundementis, and dide tho, he schal lyue in lijf.", "rotherham": "Will ye then say. Why hath not the son borne a part of the iniquity of the father? But the son hath done justice and righteousness, All my statutes, hath observed and done them He shall surely live.", "darby": "And ye say, Why doth not the son bear the iniquity of the father? But the son hath done judgment and justice, hath kept all my statutes, and hath done them; he shall certainly live.", "twenty": "", "jps": "Yet say ye: Why doth not the son bear the iniquity of the father with him? When the son hath done that which is lawful and right, and hath kept all My statutes, and hath done them, he shall surely live.", "acv": "Yet ye say, Why does not the son bear the iniquity of the father? When the son has done that which is lawful and right, and has kept all my statutes, and has done them, he shall surely live.", "anderson": "", "haweis": "", "noyes": "Yet say ye, \"Why? Doth not the son bear the iniquity of the father?\" When the son doeth that which is lawful and right, keepeth all my statutes and doeth them, he shall surely live.", "webster": "Yet say ye, Why? doth not the son bear the iniquity of the father? When the son hath done that which is lawful and right, [and] hath kept all my statutes, and hath done them, he shall surely live.", "vulgate": "et dicitis quare non portavit filius iniquitatem patris videlicet quia filius iudicium et iustitiam operatus est omnia praecepta mea custodivit et fecit illa vita vivet;", "brenton": "But ye will say, Why has not the son borne the iniquity of the father? Because the son has wrought judgment and mercy, has kept all my statues, and done them, he shall surely live."}}, {"v": 20, "ref": "18:20", "o": "הַ/נֶּ֥פֶשׁ הַ/חֹטֵ֖את הִ֣יא תָמ֑וּת בֵּ֞ן לֹא יִשָּׂ֣א בַּ/עֲוֺ֣ן הָ/אָ֗ב וְ/אָב֙ לֹ֤א יִשָּׂא֙ בַּ/עֲוֺ֣ן הַ/בֵּ֔ן צִדְקַ֤ת הַ/צַּדִּיק֙ עָלָ֣י/ו תִּֽהְיֶ֔ה וְ/רִשְׁעַ֥ת רשע הָ/רָשָׁ֖ע עָלָ֥י/ו תִּֽהְיֶֽה", "en": {"kjv": "The soul that sinneth, it shall die. The son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son: the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "web": "The soul who sins, he shall die: the son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son; the righteousness of the righteous shall be on him, and the wickedness of the wicked shall be on him.", "bsb": "The soul who sins is the one who will die. A son will not bear the iniquity of his father, and a father will not bear the iniquity of his son. The righteousness of the righteous man will fall upon him, and the wickedness of the wicked man will fall upon him.", "asv": "The soul that sinneth, it shall die: the son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son; the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "ylt": "The soul that doth sin--it doth die. A son doth not bear of the iniquity of the father, And a father doth not bear of the iniquity of the son, The righteousness of the righteous is on him, And the wickedness of the wicked is on him.", "dra": "The soul that sinneth, the same shall die: the son shall not bear the iniquity of the father, and the father shall not bear the iniquity of the son: the justice of the just shall be upon him, and the wickedness of the wicked shall be upon him.", "bbe": "The soul which does sin will be put to death: the son will not be made responsible for the evil-doing of the father, or the father for the evil-doing of the son; the righteousness of the upright will be on himself, and the evil-doing of the evil-doer on himself.", "geneva": "The same soule that sinneth, shall die: the sonne shall not beare the iniquitie of the father, neither shall the father beare the iniquitie of the sonne, but the righteousnes of the righteous shall be vpon him, and the wickednesse of the wicked shall be vpon him selfe.", "wycliffe": "Thilke soule that doith synne, schal die; the sone schal not bere the wickidnesse of the fadir, and the fadir schal not bere the wickednesse of the sone; the riytfulnesse of a iust man schal be on hym, and the wickidnesse of a wickid man schal be on hym.", "rotherham": "The person that sinneth, the same, shall die,— A, son, shall not bear a part of the iniquity of, the father Neither shall, a father, bear a part of the iniquity of the son, the righteousness of the righteous, upon himself, shall be. And, the lawlessness of a lawless man, upon himself, shall be.", "darby": "The soul that sinneth, it shall die. The son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son; the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "twenty": "", "jps": "The soul that sinneth, it shall die; the son shall not bear the iniquity of the father with him, neither shall the father bear the iniquity of the son with him; the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "acv": "The soul that sins, it shall die. The son shall not bear the iniquity of the father, nor shall the father bear the iniquity of the son. The righteousness of a righteous man shall be upon him, and the wickedness of a wicked man shall be upon him.", "anderson": "", "haweis": "", "noyes": "The soul that sinneth, it shall die. The son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son. The righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "webster": "The soul that sinneth, it shall die. The son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son: the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.", "vulgate": "anima quae peccaverit ipsa morietur filius non portabit iniquitatem patris et pater non portabit iniquitatem filii iustitia iusti super eum erit et impietas impii erit super eum;", "brenton": "But the soul that sins shall die: and the son shall not bear the iniquity of the father, nor shall the father bear the iniquity of the son: the righteousness of the righteous shall be upon him, and the iniquity of the transgressor shall be upon him."}}, {"v": 21, "ref": "18:21", "o": "וְ/הָ/רָשָׁ֗ע כִּ֤י יָשׁוּב֙ מִ/כָּל חטאת/ו חַטֹּאתָי/ו֙ אֲשֶׁ֣ר עָשָׂ֔ה וְ/שָׁמַר֙ אֶת כָּל חֻקּוֹתַ֔/י וְ/עָשָׂ֥ה מִשְׁפָּ֖ט וּ/צְדָקָ֑ה חָיֹ֥ה יִחְיֶ֖ה לֹ֥א יָמֽוּת", "en": {"kjv": "But if the wicked will turn from all his sins that he hath committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "web": "But if the wicked turn from all his sins that he has committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "bsb": "But if the wicked man turns from all the sins he has committed, keeps all My statutes, and does what is just and right, he will surely live; he will not die.", "asv": "But if the wicked turn from all his sins that he hath committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "ylt": "And the wicked--when he turneth back From all his sins that he hath done, And he hath kept all My statutes, And hath done judgment and righteousness, He doth surely live, he doth not die.", "dra": "But if the wicked do penance for all his sins which he hath committed, and keep all my commandments, and do judgment, and justice, living he shall live, and shall not die.", "bbe": "But if the evil-doer, turning away from all the sins which he has done, keeps my rules and does what is ordered and right, life will certainly be his; death will not be his fate.", "geneva": "But if the wicked will returne from all his sinnes that he hath committed, and keepe all my statutes, and doe that which is lawfull and right, he shall surely liue, and shall not die.", "wycliffe": "Forsothe if a wickid man doith penaunce of alle hise synnes whiche he wrouyte, and kepith alle myn heestis, and doith dom and riytfulnesse, he schal lyue bi lijf, and schal not die.", "rotherham": "But as for the lawless man— When he shall turn back from all his sins which he hath committed, And observe all my statutes, And do justice and righteousness He shall surely live. He shall not die:", "darby": "And the wicked, if he turn from all his sins which he hath committed, and keep all my statutes, and do judgment and justice, he shall certainly live, he shall not die.", "twenty": "", "jps": "But if the wicked turn from all his sins that he hath committed, and keep all My statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "acv": "But if a wicked man turns from all his sins that he has committed, and keeps all my statutes, and does that which is lawful and right, he shall surely live. He shall not die.", "anderson": "", "haweis": "", "noyes": "But if the wicked will turn from all his sins which he hath committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "webster": "But if the wicked will turn from all his sins that he hath committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.", "vulgate": "si autem impius egerit paenitentiam ab omnibus peccatis suis quae operatus est et custodierit universa praecepta mea et fecerit iudicium et iustitiam vita vivet non morietur;", "brenton": "And if the transgressor turn away from all his iniquities which he has committed, and keep all my commandments, and do justice and mercy, he shall surely live, and shall by no means die."}}, {"v": 22, "ref": "18:22", "o": "כָּל פְּשָׁעָי/ו֙ אֲשֶׁ֣ר עָשָׂ֔ה לֹ֥א יִזָּכְר֖וּ ל֑/וֹ בְּ/צִדְקָת֥/וֹ אֲשֶׁר עָשָׂ֖ה יִֽחְיֶֽה", "en": {"kjv": "All his transgressions that he hath committed, they shall not be mentioned unto him: in his righteousness that he hath done he shall live.", "web": "None of his transgressions that he has committed shall be remembered against him: in his righteousness that he has done he shall live.", "bsb": "None of the transgressions he has committed will be held against him. Because of the righteousness he has practiced, he will live.", "asv": "None of his transgressions that he hath committed shall be remembered against him: in his righteousness that he hath done he shall live.", "ylt": "All his transgressions that he hath done Are not remembered to him, In his righteousness that he hath done he liveth.", "dra": "I will not remember all his iniquities that he hath done: in his justice which he hath wrought, he shall live.", "bbe": "Not one of the sins which he has done will be kept in memory against him: in the righteousness which he has done he will have life.", "geneva": "All his transgressions that he hath committed, they shall not be mentioned vnto him, but in his righteousnes that he hath done, he shall liue.", "wycliffe": "Y schal not haue mynde of alle his wickidnessis whiche he wrouyte; he schal lyue in his riytfulnesse which he wrouyte.", "rotherham": "None of his transgressions which he hath committed shall be remembered against him, —In his righteousness which he hath done, he shall live.", "darby": "None of his transgressions which he hath committed shall be remembered against him; in his righteousness which he hath done shall he live.", "twenty": "", "jps": "None of his transgressions that he hath committed shall be remembered against him; for his righteousness that he hath done he shall live.", "acv": "None of his transgressions that he has committed shall be remembered against him. In his righteousness that he has done he shall live.", "anderson": "", "haweis": "", "noyes": "None of his transgressions which he hath committed shall be remembered unto him; for his righteousness, which he hath done, he shall live.", "webster": "All his transgressions that he hath committed, they shall not be mentioned to him: in his righteousness that he hath done he shall live.", "vulgate": "omnium iniquitatum eius quas operatus est non recordabor in iustitia sua quam operatus est vivet;", "brenton": "None of his trespasses which he has committed shall be remembers: in his righteousness which he has done he shall live."}}, {"v": 23, "ref": "18:23", "o": "הֶ/חָפֹ֤ץ אֶחְפֹּץ֙ מ֣וֹת רָשָׁ֔ע נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה הֲ/ל֛וֹא בְּ/שׁוּב֥/וֹ מִ/דְּרָכָ֖י/ו וְ/חָיָֽה", "en": {"kjv": "Have I any pleasure at all that the wicked should die? saith the Lord God: and not that he should return from his ways, and live?", "web": "Have I any pleasure in the death of the wicked? says the Lord Yahweh; and not rather that he should return from his way, and live?", "bsb": "Do I take any pleasure in the death of the wicked? declares the Lord GOD. Wouldn’t I prefer that he turn from his ways and live?", "asv": "Have I any pleasure in the death of the wicked? saith the Lord Jehovah; and not rather that he should return from his way, and live?", "ylt": "Do I at all desire the death of the wicked? An affirmation of the Lord Jehovah, Is it not in his turning back from his way--And he hath lived?", "dra": "Is it my will that a sinner should die, saith the Lord God, and not that he should be converted from his ways, and live?", "bbe": "Have I any pleasure in the death of the evil-doer? says the Lord: am I not pleased if he is turned from his way so that he may have life?", "geneva": "Haue I any desire that the wicked should die, sayth the Lord God? or shall he not liue, if he returne from his wayes?", "wycliffe": "Whether the deth of the wickid man is of my wille, seith the Lord God, and not that he be conuertid fro his weies, and lyue?", "rotherham": "Could I take delight, in the death of the lawless? Demandeth My Lord. Yahweh. Must it not be in his turning from his ways in which case he shall live?", "darby": "Have I any pleasure at all in the death of the wicked? saith the Lord Jehovah; is it not in his turning from his way, that he may live?", "twenty": "", "jps": "Have I any pleasure at all that the wicked should die? saith the L-rd GOD; and not rather that he should return from his ways, and live?", "acv": "Have I any pleasure in the death of a wicked man? says the lord Jehovah, and not rather that he should return from his way, and live?", "anderson": "", "haweis": "", "noyes": "Have I any pleasure at all that the wicked should die, saith the Lord Jehovah, and not that he should turn from his ways and live?", "webster": "Have I any pleasure at all that the wicked should die? saith the Lord GOD: [and] not that he should return from his ways, and live?", "vulgate": "numquid voluntatis meae est mors impii dicit Dominus Deus et non ut convertatur a viis suis et vivat;", "brenton": "Shall I at all desire death of the sinner, saith the Lord, as I desire that he should turn from his evil way, and live?"}}, {"v": 24, "ref": "18:24", "o": "וּ/בְ/שׁ֨וּב צַדִּ֤יק מִ/צִּדְקָת/וֹ֙ וְ/עָ֣שָׂה עָ֔וֶל כְּ/כֹ֨ל הַ/תּוֹעֵב֜וֹת אֲשֶׁר עָשָׂ֧ה הָ/רָשָׁ֛ע יַעֲשֶׂ֖ה וָ/חָ֑י כָּל צדקת/ו צִדְקֹתָ֤י/ו אֲשֶׁר עָשָׂה֙ לֹ֣א תִזָּכַ֔רְנָה בְּ/מַעֲל֧/וֹ אֲשֶׁר מָעַ֛ל וּ/בְ/חַטָּאת֥/וֹ אֲשֶׁר חָטָ֖א בָּ֥/ם יָמֽוּת", "en": {"kjv": "But when the righteous turneth away from his righteousness, and committeth iniquity, and doeth according to all the abominations that the wicked man doeth, shall he live? All his righteousness that he hath done shall not be mentioned: in his trespass that he hath trespassed, and in his sin that he hath sinned, in them shall he die.", "web": "But when the righteous turns away from his righteousness, and commits iniquity, and does according to all the abominations that the wicked man does, shall he live? None of his righteous deeds that he has done shall be remembered: in his trespass that he has trespassed, and in his sin that he has sinned, in them shall he die.", "bsb": "But if a righteous man turns from his righteousness and practices iniquity, committing the same abominations as the wicked, will he live? None of the righteous acts he did will be remembered. Because of the unfaithfulness and sin he has committed, he will die.", "asv": "But when the righteous turneth away from his righteousness, and committeth iniquity, and doeth according to all the abominations that the wicked man doeth, shall he live? None of his righteous deeds that he hath done shall be remembered: in his trespass that he hath trespassed, and in his sin that he hath sinned, in them shall he die.", "ylt": "And in the turning back of the righteous from his righteousness, And he hath done perversity, According to all the abominations That the wicked hath done, he doth--thus he liveth, All his righteousnesses that he hath done are not remembered, For his trespass that he hath trespassed, And for his sin that he hath sinned, For them he doth die.", "dra": "But if the just man turn himself away from his justice, and do iniquity according to all the abominations which the wicked man useth to work, shall he live? all his justices which he hath done, shall not be remembered: in the prevarication, by which he hath prevaricated, and in his sin, which he hath committed, in them he shall die.", "bbe": "But when the upright man, turning away from his righteousness, does evil, like all the disgusting things which the evil man does, will he have life? Not one of his upright acts will be kept in memory: in the wrong which he has done and in his sin death will overtake him.", "geneva": "But if the righteous turne away from his righteousnes, and commit iniquitie, and doe according to all the abominations, that the wicked man doeth, shall he liue? all his righteousnes that he hath done, shall not be mentioned: but in his transgression that he hath committed, and in his sinne that he hath sinned, in them shall he die.", "wycliffe": "Forsothe if a iust man turneth awey hym silf fro his riytfulnesse, and doith wickidnesse bi alle hise abhomynaciouns, which a wickid man is wont to worche, whether he schal lyue? Alle hise riytfulnessis whiche he dide, schulen not be had in mynde; in his trespassyng bi which he trespasside, and in his synne which he synnede, he schal die in tho.", "rotherham": "But, when a righteous man, shall turn away, from his righteousness and do that which is perverse, Shall do, according to all the abominations which the lawless man hath done, Shall he live? None of his righteous acts which he hath done, shall be remembered, In his treachery wherein he hath been treacherous, And in his sin wherein he hath sinned, In them, shall he die.", "darby": "And when the righteous turneth from his righteousness and practiseth what is wrong, [and] doeth according to all the abominations that the wicked doeth, shall he live? None of his righteous acts which he hath done shall be remembered: in his unfaithfulness which he hath wrought, and in his sin which he hath sinned, in them shall he die.", "twenty": "", "jps": "But when the righteous turneth away from his righteousness, and committeth iniquity, and doeth according to all the abominations that the wicked man doeth, shall he live? None of his righteous deeds that he hath done shall be remembered; for his trespass that he trespassed, and for his sin that he hath sinned, for them shall he die.", "acv": "But when a righteous man turns away from his righteousness, and commits iniquity, and does according to all the abominations that a wicked man does, shall he live? None of his righteous deeds that he has done shall be remembered. In his trespass that he has trespassed, and in his sin that he has sinned, in them he shall die.", "anderson": "", "haweis": "", "noyes": "But when the righteous turneth from his righteousness, and committeth iniquity, and doeth according to all the abominations which the wicked man doeth, shall he live? All his righteousness which he hath done shall not be remembered; for his trespass which he hath trespassed, and for his sin which he hath sinned, for them shall he die.", "webster": "But when the righteous turneth away from his righteousness, and committeth iniquity, [and] doeth according to all the abominations that the wicked [man] doeth, shall he live? All his righteousness that he hath done shall not be mentioned: in his trespass that he hath trespassed, and in his sin that he hath sinned, in them shall he die.", "vulgate": "si autem averterit se iustus a iustitia sua et fecerit iniquitatem secundum omnes abominationes quas operari solet impius numquid vivet omnes iustitiae eius quas fecerat non recordabuntur in praevaricatione qua praevaricatus est et in peccato suo quod peccavit in ipsis morietur;", "brenton": "But when the righteous man turns away from his righteousness, and commits iniquity, according to all the transgressions which the transgressor has wrought, none of his righteousness which he has wrought shall be at all remembered: in his trespass wherein he has trespassed, and in his sins wherein he has sinned, in them shall he die."}}, {"v": 25, "ref": "18:25", "o": "וַ/אֲמַרְתֶּ֕ם לֹ֥א יִתָּכֵ֖ן דֶּ֣רֶךְ אֲדֹנָ֑/י שִׁמְעוּ נָא֙ בֵּ֣ית יִשְׂרָאֵ֔ל הֲ/דַרְכִּ/י֙ לֹ֣א יִתָּכֵ֔ן הֲ/לֹ֥א דַרְכֵי/כֶ֖ם לֹ֥א יִתָּכֵֽנוּ", "en": {"kjv": "Yet ye say, The way of the Lord is not equal. Hear now, O house of Israel; Is not my way equal? are not your ways unequal?", "web": "Yet you say, The way of the Lord is not equal. Hear now, house of Israel: Is my way not equal? Aren’t your ways unequal?", "bsb": "Yet you say, ‘The way of the Lord is not just.’ Hear now, O house of Israel: Is it My way that is unjust? Is it not your ways that are unjust?", "asv": "Yet ye say, The way of the Lord is not equal. Hear now, O house of Israel: Is not my way equal? are not your ways unequal?", "ylt": "And ye have said, Not pondered is the way of the Lord. Hear, I pray you, O house of Israel, My way--is it not pondered? Are not your ways unpondered?", "dra": "And you have said: The way of the Lord is not right. Hear ye, therefore, O house of Israel: Is it my way that is not right, and are not rather your ways perverse?", "bbe": "But you say, The way of the Lord is not equal. Give ear, now, O children of Israel; is my way not equal? are not your ways unequal?", "geneva": "Yet ye say, The way of the Lord is not equall: heare now, O house of Israel. Is not my way equall? or are not your wayes vnequall?", "wycliffe": "And ye seiden, The weie of the Lord is not euene. Therfor, the hous of Israel, here ye, whether my weie is not euene, and not more youre weies ben schrewid?", "rotherham": "Can ye then say— The way of My Lord will not be equal? Hear I pray you O house of Israel, Will my way, not be equal? Will not your ways be unequal?", "darby": "And ye say, The way of the Lord is not equal. Hear then, house of Israel. Is not my way equal? are not your ways unequal?", "twenty": "", "jps": "Yet ye say: The way of the L-rd is not equal. Hear now, O house of Israel: Is it My way that is not equal? is it not your ways that are unequal?", "acv": "Yet ye say, The way of the Lord is not equitable. Hear now, O house of Israel. Is not my way equitable? Are not your ways inequitable?", "anderson": "", "haweis": "", "noyes": "Yet ye say, \"The way of the Lord is not right.\" Hear now, O house of Israel! \"Is not my way right?\" Is it not your ways that are not right?", "webster": "Yet ye say, The way of the Lord is not equal. Hear now, O house of Israel; Is not my way equal? are not your ways unequal?", "vulgate": "et dixistis non est aequa via Domini audite domus Israhel numquid via mea non est aequa et non magis viae vestrae pravae sunt;", "brenton": "Yet ye have said, The way of the Lord is not straight. Hear now, all the house of Israel; will not my way be straight? Is your way straight?"}}, {"v": 26, "ref": "18:26", "o": "בְּ/שׁוּב צַדִּ֧יק מִ/צִּדְקָת֛/וֹ וְ/עָ֥שָׂה עָ֖וֶל וּ/מֵ֣ת עֲלֵי/הֶ֑ם בְּ/עַוְל֥/וֹ אֲשֶׁר עָשָׂ֖ה יָמֽוּת", "en": {"kjv": "When a righteous man turneth away from his righteousness, and committeth iniquity, and dieth in them; for his iniquity that he hath done shall he die.", "web": "When the righteous man turns away from his righteousness, and commits iniquity, and dies therein; in his iniquity that he has done shall he die.", "bsb": "If a righteous man turns from his righteousness and practices iniquity, he will die for this. He will die because of the iniquity he has committed.", "asv": "When the righteous man turneth away from his righteousness, and committeth iniquity, and dieth therein; in his iniquity that he hath done shall he die.", "ylt": "In the turning back of the righteous from his righteousness, And he hath done perversity, And he is dying by them, for his perversity That he hath done he dieth.", "dra": "For when the just turneth himself away from his justice, and comitteth iniquity, he shall die therein: in the injustice that he hath wrought he shall die.", "bbe": "When the upright man, turning away from his righteousness, does evil, death will overtake him; in the evil which he has done death will overtake him.", "geneva": "For when a righteous man turneth away from his righteousnes, and committeth iniquitie, he shall euen die for the same, he shall euen die for his iniquitie, that he hath done.", "wycliffe": "For whanne a riytful man turneth awei hym silf fro his riytfulnesse, and doith wickidnesse, he schal die in it, he schal die in the vnriytwisnesse which he wrouyte.", "rotherham": "When a righteous man shall turn away from his righteousness and do that which is perverse and die because of those things In his own perversity which he hath done, shall he die.", "darby": "When the righteous turneth away from his righteousness, and practiseth what is wrong, and dieth for it; in his wrong that he hath done shall he die.", "twenty": "", "jps": "When the righteous man turneth away from his righteousness, and committeth iniquity, he shall die therefor; for his iniquity that he hath done shall he die.", "acv": "When a righteous man turns away from his righteousness, and commits iniquity, and dies in it, in his iniquity that he has done, he shall die.", "anderson": "", "haweis": "", "noyes": "When a righteous man turneth from his righteousness, and committeth iniquity, and on this account dieth, for his iniquity which he hath done doth he die.", "webster": "When a righteous [man] turneth away from his righteousness, and committeth iniquity, and dieth in them; for his iniquity that he hath done shall he die.", "vulgate": "cum enim averterit se iustus a iustitia sua et fecerit iniquitatem morietur in eis in iniustitia quam operatus est morietur;", "brenton": "When the righteous turns away from his righteousness and commits a trespass, and dies in the trespass he has committed, he shall even die in it."}}, {"v": 27, "ref": "18:27", "o": "וּ/בְ/שׁ֣וּב רָשָׁ֗ע מֵֽ/רִשְׁעָת/וֹ֙ אֲשֶׁ֣ר עָשָׂ֔ה וַ/יַּ֥עַשׂ מִשְׁפָּ֖ט וּ/צְדָקָ֑ה ה֖וּא אֶת נַפְשׁ֥/וֹ יְחַיֶּֽה", "en": {"kjv": "Again, when the wicked man turneth away from his wickedness that he hath committed, and doeth that which is lawful and right, he shall save his soul alive.", "web": "Again, when the wicked man turns away from his wickedness that he has committed, and does that which is lawful and right, he shall save his soul alive.", "bsb": "But if a wicked man turns from the wickedness he has committed and does what is just and right, he will save his life.", "asv": "Again, when the wicked man turneth away from his wickedness that he hath committed, and doeth that which is lawful and right, he shall save his soul alive.", "ylt": "And in the turning back of the wicked From his wickedness that he hath done, And he doth judgment and righteousness, He his soul doth keep alive.", "dra": "And when the wicked turneth himself away from his wickedness, which he hath wrought, and doeth judgment, and justice: he shall save his soul alive.", "bbe": "Again, when the evil-doer, turning away from the evil he has done, does what is ordered and right, he will have life for his soul.", "geneva": "Againe when the wicked turneth away from his wickednes that he hath committed, and doeth that which is lawfull and right, he shall saue his soule aliue.", "wycliffe": "And whanne a wickid man turneth awei him silf fro his wickidnesse which he wrouyte, and doith dom and riytfulnesse, he schal quykene his soule.", "rotherham": "But when a lawless man turneth away from his lawlessness which he hath done, And hath done justice and righteousness He, shall save his own soul, alive:", "darby": "And when the wicked turneth from his wickedness which he hath committed, and doeth judgment and justice, he shall keep his soul alive.", "twenty": "", "jps": "Again, when the wicked man turneth away from his wickedness that he hath committed, and doeth that which is lawful and right, he shall save his soul alive.", "acv": "Again, when a wicked man turns away from his wickedness that he has committed, and does that which is lawful and right, he shall save his soul alive.", "anderson": "", "haweis": "", "noyes": "And when the wicked man turneth from his iniquity which he hath committed, and doeth that which is lawful and right, he shall save his soul alive.", "webster": "Again, when a wicked [man] turneth away from his wickedness that he hath committed, and doeth that which is lawful and right, he shall save his soul alive.", "vulgate": "et cum averterit se impius ab impietate sua quam operatus est et fecerit iudicium et iustitiam ipse animam suam vivificabit;", "brenton": "And when the wicked man turns away from his wickedness that he has committed, and shall do judgment and justice, he has kept his soul,"}}, {"v": 28, "ref": "18:28", "o": "וַ/יִּרְאֶ֣ה ו/ישוב וַ/יָּ֔שָׁב מִ/כָּל פְּשָׁעָ֖י/ו אֲשֶׁ֣ר עָשָׂ֑ה חָי֥וֹ יִחְיֶ֖ה לֹ֥א יָמֽוּת", "en": {"kjv": "Because he considereth, and turneth away from all his transgressions that he hath committed, he shall surely live, he shall not die.", "web": "Because he considers, and turns away from all his transgressions that he has committed, he shall surely live, he shall not die.", "bsb": "Because he considered and turned from all the transgressions he had committed, he will surely live; he will not die.", "asv": "Because he considereth, and turneth away from all his transgressions that he hath committed, he shall surely live, he shall not die.", "ylt": "And he seeth and turneth back, From all his transgressions that he hath done, He doth surely live, he doth not die,", "dra": "Because he considereth and turneth away himself from all his iniquities which he hath wrought, he shall surely live, and not die.", "bbe": "Because he had fear and was turned away from all the wrong which he had done, life will certainly be his, death will not be his fate.", "geneva": "Because he considereth, and turneth away from all his transgressions that hee hath committed, he shall surely liue and shall not die.", "wycliffe": "For he biholdinge and turnynge awei hym silf fro alle hise wickidnessis which he wrouyte, schal lyue in lijf, and schal not die.", "rotherham": "When he considered, then he turned away from all his transgressions which he had committed, He shall surely live. He shall not die.", "darby": "Because he considereth, and turneth from all his transgressions which he hath committed, he shall certainly live, he shall not die.", "twenty": "", "jps": "Because he considereth, and turneth away from all his transgressions that he hath committed, he shall surely live, he shall not die.", "acv": "Because he considers, and turns away from all his transgressions that he has committed, he shall surely live. He shall not die.", "anderson": "", "haweis": "", "noyes": "Because he considereth and turneth from all his transgressions which he hath committed, he shall surely live, he shall not die.", "webster": "Because he considereth and turneth away from all his transgressions that he hath committed, he shall surely live, he shall not die.", "vulgate": "considerans enim et avertens se ab omnibus iniquitatibus suis quas operatus est vita vivet et non morietur;", "brenton": "and has turned away from all his ungodliness which he has committed: he shall surely live, he shall not die."}}, {"v": 29, "ref": "18:29", "o": "וְ/אָֽמְרוּ֙ בֵּ֣ית יִשְׂרָאֵ֔ל לֹ֥א יִתָּכֵ֖ן דֶּ֣רֶךְ אֲדֹנָ֑/י הַ/דְּרָכַ֞/י לֹ֤א יִתָּֽכְנּוּ֙ בֵּ֣ית יִשְׂרָאֵ֔ל הֲ/לֹ֥א דַרְכֵי/כֶ֖ם לֹ֥א יִתָּכֵֽן", "en": {"kjv": "Yet saith the house of Israel, The way of the Lord is not equal. O house of Israel, are not my ways equal? are not your ways unequal?", "web": "Yet the house of Israel says, “The way of the Lord is not fair.” House of Israel, aren’t my ways fair? Aren’t your ways unfair?", "bsb": "Yet the house of Israel says, ‘The way of the Lord is not just.’ Are My ways unjust, O house of Israel? Is it not your ways that are unjust?", "asv": "Yet saith the house of Israel, The way of the Lord is not equal. O house of Israel, are not my ways equal? are not your ways unequal?", "ylt": "And the house of Israel have said, Not pondered is the way of the Lord, My ways--are they not pondered? O house of Israel--are not your ways unpondered?", "dra": "And the children of Israel say: The way of the Lord is not right. Are not my ways right, O house of Israel, and are not rather your ways perverse?", "bbe": "But still the children of Israel say, The way of the Lord is not equal. O children of Israel, are my ways not equal? are not your ways unequal?", "geneva": "Yet saith ye house of Israel, The way of the Lord is not equall. O house of Israel, are not my wayes equall? or are not your wayes vnequall?", "wycliffe": "And the sones of Israel seien, The weie of the Lord is not euene. Whether my weies ben not euene, ye hous of Israel, and not more youre weies ben schrewid?", "rotherham": "Can the house of Israel then say- The way of My Lord will not be equal? Will my ways, not be equal O house of Israel? Will not your ways be unequal?", "darby": "But the house of Israel say, The way of the Lord is not equal. O house of Israel, are not my ways equal? Is it not your ways that are unequal?", "twenty": "", "jps": "Yet saith the house of Israel: The way of the L-rd is not equal. O house of Israel, is it My ways that are not equal? is it not your ways that are unequal?", "acv": "Yet the house of Israel says, The way of the Lord is not equitable. O house of Israel, are not my ways equitable? Are not your ways inequitable?", "anderson": "", "haweis": "", "noyes": "Yet saith the house of Israel, \"The way of the Lord is not right.\" O house of Israel, are not my ways right? Is it not your ways that are not right?", "webster": "Yet saith the house of Israel, The way of the Lord is not equal. O house of Israel, are not my ways equal? are not your ways unequal?", "vulgate": "et dicunt filii Israhel non est aequa via Domini numquid viae meae non sunt aequae domus Israhel et non magis viae vestrae pravae;", "brenton": "Yet the house of Israel say, The way of the Lord is not right. Is not my way right, O house of Israel? is not your way wrong?"}}, {"v": 30, "ref": "18:30", "o": "לָ/כֵן֩ אִ֨ישׁ כִּ/דְרָכָ֜י/ו אֶשְׁפֹּ֤ט אֶתְ/כֶם֙ בֵּ֣ית יִשְׂרָאֵ֔ל נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה שׁ֤וּבוּ וְ/הָשִׁ֨יבוּ֙ מִ/כָּל פִּשְׁעֵי/כֶ֔ם וְ/לֹֽא יִהְיֶ֥ה לָ/כֶ֛ם לְ/מִכְשׁ֖וֹל עָוֺֽן", "en": {"kjv": "Therefore I will judge you, O house of Israel, every one according to his ways, saith the Lord God. Repent, and turn yourselves from all your transgressions; so iniquity shall not be your ruin.", "web": "Therefore I will judge you, house of Israel, everyone according to his ways, says the Lord Yahweh. Return, and turn yourselves from all your transgressions; so iniquity shall not be your ruin.", "bsb": "Therefore, O house of Israel, I will judge you, each according to his ways, declares the Lord GOD. Repent and turn from all your transgressions, so that your iniquity will not become your downfall.", "asv": "Therefore I will judge you, O house of Israel, every one according to his ways, saith the Lord Jehovah. Return ye, and turn yourselves from all your transgressions; so iniquity shall not be your ruin.", "ylt": "Therefore, each according to his ways I judge you, O house of Israel? An affirmation of the Lord Jehovah, Turn ye back, yea, turn yourselves back, From all your transgressions, And iniquity is not to you for a stumbling-block,", "dra": "Therefore will I judge every man according to his ways, O house of Israel, saith the Lord God. Be converted, and do penance for all your iniquities: and iniquity shall not be your ruin.", "bbe": "For this cause I will be your judge, O children of Israel, judging every man by his ways, says the Lord. Come back and be turned from all your sins; so that they may not be the cause of your falling into evil.", "geneva": "Therefore I will iudge you, O house of Israel, euery one according to his wayes, sayth the Lord God: returne therefore and cause others to turne away from all your transgressions: so iniquitie shall not be your destruction.", "wycliffe": "Therfor, thou hous of Israel, Y schal deme ech man bi hise weies, seith the Lord God. Turne ye togidere, and do ye penaunce for alle youre wickidnessis, and wickidnesse schal not be to you in to falling.", "rotherham": "Therefore, Every man according to his own ways, will I judge you O house of Israel, Declareth My Lord Yahweh, Return ye—and make good your return—from all your transgressions, That they become not unto you a stumbling block of iniquity.", "darby": "Therefore I will judge you, house of Israel, every one according to his ways, saith the Lord Jehovah. Return ye, and turn from all your transgressions; so iniquity shall not be your snare.", "twenty": "", "jps": "Therefore I will judge you, O house of Israel, every one according to his ways, saith the L-rd GOD. Return ye, and turn yourselves from all your transgressions; so shall they not be a stumblingblock of iniquity unto you.", "acv": "Therefore I will judge you, O house of Israel, each one according to his ways, says the lord Jehovah. Return ye, and turn yourselves from all your transgressions, so iniquity shall not be your ruin.", "anderson": "", "haweis": "", "noyes": "Therefore I will judge you, O house of Israel, every one according to his ways, saith the Lord Jehovah. Turn ye, turn yourselves from all your transgressions, so that iniquity may not be your ruin.", "webster": "Therefore I will judge you, O house of Israel, every one according to his ways, saith the Lord GOD. Repent, and turn [yourselves] from all your transgressions; so iniquity shall not be your ruin.", "vulgate": "idcirco unumquemque iuxta vias suas iudicabo domus Israhel ait Dominus Deus convertimini et agite paenitentiam ab omnibus iniquitatibus vestris et non erit vobis in ruinam iniquitas;", "brenton": "I will judge you, O house of Israel, saith the Lord, each one according to his way: be converted, and turn from all your ungodliness, and it shall not become to you the punishment of iniquity."}}, {"v": 31, "ref": "18:31", "o": "הַשְׁלִ֣יכוּ מֵ/עֲלֵי/כֶ֗ם אֶת כָּל פִּשְׁעֵי/כֶם֙ אֲשֶׁ֣ר פְּשַׁעְתֶּ֣ם בָּ֔/ם וַ/עֲשׂ֥וּ לָ/כֶ֛ם לֵ֥ב חָדָ֖שׁ וְ/ר֣וּחַ חֲדָשָׁ֑ה וְ/לָ֥/מָּה תָמֻ֖תוּ בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Cast away from you all your transgressions, whereby ye have transgressed; and make you a new heart and a new spirit: for why will ye die, O house of Israel?", "web": "Cast away from you all your transgressions, in which you have transgressed; and make yourself a new heart and a new spirit: for why will you die, house of Israel?", "bsb": "Cast away from yourselves all the transgressions you have committed, and fashion for yourselves a new heart and a new spirit. Why should you die, O house of Israel?", "asv": "Cast away from you all your transgressions, wherein ye have transgressed; and make you a new heart and a new spirit: for why will ye die, O house of Israel?", "ylt": "Cast from off you all your transgressions, By which ye have transgressed, And make to you a new heart, and a new spirit, And why do ye die, O house of Israel?", "dra": "Cast away from you all your transgressions, by which you have transgressed, and make to yourselves a new heart, and a new spirit: and why will you die, O house of Israel?", "bbe": "Put away all your evil-doing in which you have done sin; and make for yourselves a new heart and a new spirit: why are you desiring death, O children of Israel?", "geneva": "Cast away from you all your transgressions, whereby ye haue transgressed, and make you a newe heart and a new spirit: for why will ye die, O house of Israel?", "wycliffe": "Caste awei fro you alle youre trespassingis, bi whiche ye trespassiden, and make ye a newe herte and a newe spirit to you, and whi schulen ye die, the hous of Israel?", "rotherham": "Cast off from you all your transgressions which ye have committed against me, And make you a new heart; And a new spirit,- For why should ye die, O house of Israel?", "darby": "Cast away from you all your transgressions wherewith ye have transgressed, and make you a new heart and a new spirit: why then will ye die, house of Israel?", "twenty": "", "jps": "Cast away from you all your transgressions, wherein ye have transgressed; and make you a new heart and a new spirit; for why will ye die, O house of Israel?", "acv": "Cast away from you all your transgressions, by which ye have transgressed, and make you a new heart and a new spirit. For why will ye die, O house of Israel?", "anderson": "", "haweis": "", "noyes": "Cast away from you all your transgressions which ye have committed, and make you a new heart, and a new spirit! For why will ye die, O house of Israel?", "webster": "Cast away from you all your transgressions, by which ye have transgressed; and make you a new heart and a new spirit: for why will ye die, O house of Israel?", "vulgate": "proicite a vobis omnes praevaricationes vestras in quibus praevaricati estis et facite vobis cor novum et spiritum novum et quare moriemini domus Israhel;", "brenton": "Cast away from yourselves all your ungodliness wherein ye have sinned against me; and make to yourselves a new heart and a new spirit: for why should ye die, O house of Israel?"}}, {"v": 32, "ref": "18:32", "o": "כִּ֣י לֹ֤א אֶחְפֹּץ֙ בְּ/מ֣וֹת הַ/מֵּ֔ת נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה וְ/הָשִׁ֖יבוּ וִֽ/חְיֽוּ", "en": {"kjv": "For I have no pleasure in the death of him that dieth, saith the Lord God: wherefore turn yourselves, and live ye.", "web": "For I have no pleasure in the death of him who dies, says the Lord Yahweh: therefore turn yourselves, and live.", "bsb": "For I take no pleasure in anyone’s death, declares the Lord GOD. So repent and live!", "asv": "For I have no pleasure in the death of him that dieth, saith the Lord Jehovah: wherefore turn yourselves, and live.", "ylt": "For I have no pleasure in the death of the dying, An affirmation of the Lord Jehovah, And turn ye back and live!", "dra": "For I desire not the death of him that dieth, saith the Lord God, return ye and live.", "bbe": "For I have no pleasure in the death of him on whom death comes, says the Lord: be turned back then, and have life.", "geneva": "For I desire not the death of him that dyeth, sayth the Lord God: cause therefore one another to returne, and liue ye.", "wycliffe": "For Y nyle the deeth of hym that dieth, seith the Lord God; turne ye ayen, and lyue ye.", "rotherham": "For I cannot take delight in the death of him that dieth, Declareth My Lord Yahweh, Make good your return then and, live!", "darby": "For I have no pleasure in the death of him that dieth, saith the Lord Jehovah; therefore turn ye and live.", "twenty": "", "jps": "For I have no pleasure in the death of him that dieth, saith the L-rd GOD; wherefore turn yourselves, and live.", "acv": "For I have no pleasure in the death of him who dies, says the lord Jehovah, therefore turn yourselves back, and live.", "anderson": "", "haweis": "", "noyes": "For I have no pleasure in the death of him that dieth, saith the Lord Jehovah. Wherefore turn yourselves and live!", "webster": "For I have no pleasure in the death of him that dieth, saith the Lord GOD: wherefore turn [ye], and live.", "vulgate": "quia nolo mortem morientis dicit Dominus Deus revertimini et vivite;", "brenton": "For I desire not the death of him that dies, saith the Lord."}}]}, {"c": 19, "verses": [{"v": 1, "ref": "19:1", "o": "וְ/אַתָּה֙ שָׂ֣א קִינָ֔ה אֶל נְשִׂיאֵ֖י יִשְׂרָאֵֽל", "en": {"kjv": "Moreover take thou up a lamentation for the princes of Israel,", "web": "Moreover, take up a lamentation for the princes of Israel,", "bsb": "“As for you, take up a lament for the princes of Israel", "asv": "Moreover, take thou up a lamentation for the princes of Israel,", "ylt": "And thou, lift up a lamentation unto princes of Israel,", "dra": "Moreover take thou up a lamentation for the princes of Israel,", "bbe": "Take up now a song of grief for the ruler of Israel, and say,", "geneva": "Thou also, take vp a lamentation for the princes of Israel,", "wycliffe": "And thou, sone of man, take weiling on the princes of Israel;", "rotherham": "Thou. therefore take up a dirge, for the prince of Israel;", "darby": "And thou, take thou up a lamentation for the princes of Israel,", "twenty": "", "jps": "Moreover, take thou up a lamentation for the princes of Israel,", "acv": "Moreover, take thou up a lamentation for the rulers of Israel,", "anderson": "", "haweis": "", "noyes": "Moreover, take thou up a lamentation for the princes of Israel,", "webster": "Moreover take thou up a lamentation for the princes of Israel,", "vulgate": "et tu adsume planctum super principes Israhel;", "brenton": "Moreover do thou take up a lamentation for the prince of Israel,"}}, {"v": 2, "ref": "19:2", "o": "וְ/אָמַרְתָּ֗ מָ֤ה אִמְּ/ךָ֙ לְבִיָּ֔א בֵּ֥ין אֲרָי֖וֹת רָבָ֑צָה בְּ/ת֥וֹךְ כְּפִרִ֖ים רִבְּתָ֥ה גוּרֶֽי/הָ", "en": {"kjv": "And say, What is thy mother? A lioness: she lay down among lions, she nourished her whelps among young lions.", "web": "and say, What was your mother? A lioness: she couched among lions, in the midst of the young lions she nourished her cubs.", "bsb": "and say: ‘What was your mother? A lioness among the lions! She lay down among the young lions; she reared her cubs.", "asv": "and say, What was thy mother? A lioness: she couched among lions, in the midst of the young lions she nourished her whelps.", "ylt": "and thou hast said: What is thy mother? --a lioness, Among lions she hath crouched down, In the midst of young lions she hath multiplied her whelps.", "dra": "And say: Why did thy mother the lioness lie down among the lions, and bring up her whelps in the midst of young lions?", "bbe": "What was your mother? Like a she-lion among lions, stretched out among the young lions she gave food to her little ones.", "geneva": "And say, Wherefore lay thy mother as a lyonesse among the lyons? she nourished her yong ones among the lyons whelps,", "wycliffe": "and thou schalt seie, Whi thi modir, a lionesse, lai among liouns? In the myddis of litle liouns sche nurschide hir whelpis,", "rotherham": "and thou shalt say— How was thy mother a lioness, Between lions, she lay down,- In the midst of young lions, She nourished her whelps;", "darby": "and say, What was thy mother? A lioness: she lay down among lions, she nourished her whelps in the midst of the young lions.", "twenty": "", "jps": "and say: How was thy mother a lioness; among lions she couched, in the midst of the young lions she reared her whelps!", "acv": "and say, What was thy mother? A lioness. She couched among lions. In the midst of the young lions she nourished her whelps.", "anderson": "", "haweis": "", "noyes": "and say:—How lay thy mother at ease, a lioness among lions! Among young lions she nourished her whelps;", "webster": "And say, What [is] thy mother: A lioness: she lay down among lions, she nourished her whelps among young lions.", "vulgate": "et dices quare mater tua leaena inter leones cubavit in medio leunculorum enutrivit catulos suos;", "brenton": "and say, Why is thy mother become a whelp in the midst of lions? in the midst of lions she has multiplied her whelps."}}, {"v": 3, "ref": "19:3", "o": "וַ/תַּ֛עַל אֶחָ֥ד מִ/גֻּרֶ֖י/הָ כְּפִ֣יר הָיָ֑ה וַ/יִּלְמַ֥ד לִ/טְרָף טֶ֖רֶף אָדָ֥ם אָכָֽל", "en": {"kjv": "And she brought up one of her whelps: it became a young lion, and it learned to catch the prey; it devoured men.", "web": "She brought up one of her cubs: he became a young lion, and he learned to catch the prey; he devoured men.", "bsb": "She brought up one of her cubs, and he became a young lion. After learning to tear his prey, he devoured men.", "asv": "And she brought up one of her whelps: he became a young lion, and he learned to catch the prey; he devoured men.", "ylt": "And she bringeth up one of her whelps, A young lion it hath been, And it learneth to tear prey, man it hath devoured.", "dra": "And she brought out one of her whelps, and he became a lion: and he learned to catch the prey, and to devour men.", "bbe": "And one of her little ones came to growth under her care, and became a young lion, learning to go after beasts for his food; and he took men for his meat.", "geneva": "And she brought vp one of her whelps, and it became a lyon, and it learned to catch the praye, and it deuoured men.", "wycliffe": "and ledde out oon of hir litle liouns; he was maad a lioun, and he lernyde to take prei, and to ete men.", "rotherham": "And she reared up one of her whelps— A young lion, he became, And he learned to rend prey. Men, he devoured.", "darby": "And she brought up one of her whelps; it became a young lion, and he learned to catch the prey; he devoured men.", "twenty": "", "jps": "And she brought up one of her whelps, he became a young lion; and he learned to catch the prey, he devoured men.", "acv": "And she brought up one of her whelps. He became a young lion, and he learned to catch the prey. He devoured men.", "anderson": "", "haweis": "", "noyes": "And she brought up one of her whelps; He became a young lion, And he learned to seize the prey; he devoured men.", "webster": "And she brought up one of her whelps: it became a young lion, and it learned to catch the prey; it devoured men.", "vulgate": "et eduxit unum de leunculis suis leo factus est et didicit capere praedam hominemque comedere;", "brenton": "And one of her whelps sprang forth; he became a lion, and learned to take prey, he devoured men."}}, {"v": 4, "ref": "19:4", "o": "וַ/יִּשְׁמְע֥וּ אֵלָ֛י/ו גּוֹיִ֖ם בְּ/שַׁחְתָּ֣/ם נִתְפָּ֑שׂ וַ/יְבִאֻ֥/הוּ בַֽ/חַחִ֖ים אֶל אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "The nations also heard of him; he was taken in their pit, and they brought him with chains unto the land of Egypt.", "web": "The nations also heard of him; he was taken in their pit; and they brought him with hooks to the land of Egypt.", "bsb": "When the nations heard of him, he was trapped in their pit. With hooks they led him away to the land of Egypt.", "asv": "The nations also heard of him; he was taken in their pit; and they brought him with hooks unto the land of Egypt.", "ylt": "And hear of it do nations, In their pit it hath been caught, And they bring it in with chains unto the land of Egypt.", "dra": "And the nations heard of him, and took him, but not without receiving wounds: and they brought him in chains into the land of Egypt.", "bbe": "And the nations had news of him; he was taken in the hole they had made: and, pulling him with hooks, they took him into the land of Egypt.", "geneva": "The nations also heard of him, and he was taken in their nets, and they brought him in chaines vnto the land of Egypt.", "wycliffe": "And hethene men herden of hym, and token hym not withouten her woundis; and thei brouyten hym in chaynes in to the lond of Egipt.", "rotherham": "Then nations heard of him. In their pit, was he caught,— So they brought him with hooks. Into the land of Egypt.", "darby": "And the nations heard of him; he was taken in their pit, and they brought him with nose-rings into the land of Egypt.", "twenty": "", "jps": "Then the nations assembled against him, he was taken in their pit; and they brought him with hooks unto the land of Egypt.", "acv": "The nations also heard of him. He was taken in their pit, and they brought him with hooks to the land of Egypt.", "anderson": "", "haweis": "", "noyes": "And when the nations heard of him, he was taken in their pit, And they brought him with nose-rings to the land of Egypt.", "webster": "The nations also heard of him; he was taken in their pit, and they brought him with chains to the land of Egypt.", "vulgate": "et audierunt de eo gentes et non absque vulneribus suis ceperunt eum et adduxerunt eum in catenis in terram Aegypti;", "brenton": "And the nations heard a report of him; he was caught in their pit, and they brought him into the land of Egypt in chains."}}, {"v": 5, "ref": "19:5", "o": "וַ/תֵּ֨רֶא֙ כִּ֣י נֽוֹחֲלָ֔ה אָבְדָ֖ה תִּקְוָתָ֑/הּ וַ/תִּקַּ֛ח אֶחָ֥ד מִ/גֻּרֶ֖י/הָ כְּפִ֥יר שָׂמָֽתְ/הוּ", "en": {"kjv": "Now when she saw that she had waited, and her hope was lost, then she took another of her whelps, and made him a young lion.", "web": "Now when she saw that she had waited, and her hope was lost, then she took another of her cubs, and made him a young lion.", "bsb": "When she saw that she had waited in vain, that her hope was lost, she took another of her cubs and made him a young lion.", "asv": "Now when she saw that she had waited, and her hope was lost, then she took another of her whelps, and made him a young lion.", "ylt": "And she seeth, that stayed--perished hath her hope, And she taketh one of her whelps, A young lion she hath made it.", "dra": "But she seeing herself weakened, and that her hope was lost, took one of her young lions, and set him up for a lion.", "bbe": "Now when she saw that her hope was made foolish and gone, she took another of her little ones and made him into a young lion.", "geneva": "Nowe when she sawe, that she had waited and her hope was lost, she tooke another of her whelps, and made him a lyon.", "wycliffe": "Which modir whanne sche hadde seyn, that sche was sijk, and the abiding of hym perischide, took oon of her litle liouns, and made hym a lioun.", "rotherham": "And she saw she had waited Lost was her hope, Then took she another of her whelps. A young lion, she made him.", "darby": "And when she saw that she had waited [and] her hope was lost, she took another of her whelps, [and] made him a young lion.", "twenty": "", "jps": "Now when she saw that she was disappointed, and her hope was lost, then she took another of her whelps, and made him a young lion.", "acv": "Now when she saw that she had waited, and her hope was lost, then she took another of her whelps, and made him a young lion.", "anderson": "", "haweis": "", "noyes": "And when she saw that she waited in vain, and that her hope was lost, She took another of her whelps, and she made him a young lion.", "webster": "Now when she saw that she had waited, [and] her hope was lost, then she took another of her whelps, [and] made him a young lion.", "vulgate": "quae cum vidisset quoniam infirmata est et periit expectatio eius tulit unum de leunculis suis leonem constituit eum;", "brenton": "And she saw that he was driven away from her, and her hope of him perished, and she took another of her whelps; she made him a lion."}}, {"v": 6, "ref": "19:6", "o": "וַ/יִּתְהַלֵּ֥ךְ בְּ/תוֹךְ אֲרָי֖וֹת כְּפִ֣יר הָיָ֑ה וַ/יִּלְמַ֥ד לִ/טְרָף טֶ֖רֶף אָדָ֥ם אָכָֽל", "en": {"kjv": "And he went up and down among the lions, he became a young lion, and learned to catch the prey, and devoured men.", "web": "He went up and down among the lions; he became a young lion, and he learned to catch the prey; he devoured men.", "bsb": "He prowled among the lions, and became a young lion. After learning to tear his prey, he devoured men.", "asv": "And he went up and down among the lions; he became a young lion, and he learned to catch the prey; he devoured men.", "ylt": "And it goeth up and down in the midst of lions, A young lion it hath been, And it learneth to tear prey, man it hath devoured.", "dra": "And he went up and down among the lions, and became a lion: and he learned to catch the prey, and to devour men.", "bbe": "And he went up and down among the lions and became a young lion, learning to go after beasts for his food; and he took men for his meat.", "geneva": "Which went among the lyons, and became a lyon, and learned to catch the praye, and he deuoured men.", "wycliffe": "Which yede among liouns, and was maad a lioun;", "rotherham": "Yea he went to and fro amidst lions A young lion, he became,- And he learned to rend prey. Men, he devoured;", "darby": "And he went up and down among the lions; he became a young lion, and learned to catch the prey; he devoured men.", "twenty": "", "jps": "And he went up and down among the lions, he became a young lion; and he learned to catch the prey, he devoured men.", "acv": "And he went up and down among the lions. He became a young lion, and he learned to catch the prey. He devoured men.", "anderson": "", "haweis": "", "noyes": "And he went up and down among the lions; he became a young lion, And he learned to seize the prey; he devoured men.", "webster": "And he went up and down among the lions, he became a young lion, and learned to catch the prey, [and] devoured men.", "vulgate": "qui incedebat inter leones et factus est leo didicit praedam capere et homines devorare;", "brenton": "And he went up and down in the midst of lions, he became a lion, and learned to take prey, he devoured men."}}, {"v": 7, "ref": "19:7", "o": "וַ/יֵּ֨דַע֙ אַלְמְנוֹתָ֔י/ו וְ/עָרֵי/הֶ֖ם הֶחֱרִ֑יב וַ/תֵּ֤שַׁם אֶ֨רֶץ֙ וּ/מְלֹאָ֔/הּ מִ/קּ֖וֹל שַׁאֲגָתֽ/וֹ", "en": {"kjv": "And he knew their desolate palaces, and he laid waste their cities; and the land was desolate, and the fulness thereof, by the noise of his roaring.", "web": "He knew their palaces, and laid waste their cities; and the land was desolate, and its fullness, because of the noise of his roaring.", "bsb": "He broke down their strongholds and devastated their cities. The land and everything in it shuddered at the sound of his roaring.", "asv": "And he knew their palaces, and laid waste their cities; and the land was desolate, and the fulness thereof, because of the noise of his roaring.", "ylt": "And it knoweth his forsaken habitations, And their cities it hath laid waste, And desolate is the land and its fulness, Because of the voice of his roaring.", "dra": "He learned to make widows, and to lay waste their cities: and the land became desolate, and the fulness thereof by the noise of his roaring.", "bbe": "And he sent destruction on their widows and made waste their towns; and the land and everything in it became waste because of the loud sound of his voice.", "geneva": "And he knew their widowes, and he destroyed their cities, and the land was wasted, and all that was therein by the noyse of his roaring.", "wycliffe": "and lernede to take prey, and to deuoure men. He lernyde to make widewis, and to brynge the citees of men in to desert; and the lond and the fulnesse therof was maad desolat, of the vois of his roryng.", "rotherham": "And he injured his widows, And their cities, laid waste,- And deserted was the land and its fulness, At the noise of his roaring.", "darby": "And he knew their [desolate] palaces, and he laid waste their cities, so that the land was desolate, and all it contained, by the noise of his roaring.", "twenty": "", "jps": "And he knew their castles, and laid waste their cities; and the land was desolate, and the fulness thereof, because of the noise of his roaring.", "acv": "And he knew their palaces, and laid waste their cities. And the land was desolate, and the fullness of it, because of the noise of his roaring.", "anderson": "", "haweis": "", "noyes": "He knew their widows, and laid waste their cities, And the land was desolate, and all that was therein, before the voice of his roaring.", "webster": "And he knew their desolate palaces, and he laid waste their cities; and the land was desolate, and the fullness of it, by the noise of his roaring.", "vulgate": "didicit viduas facere et civitates eorum in desertum adducere et desolata est terra et plenitudo eius a voce rugitus illius;", "brenton": "And he prowled in his boldness and laid waste their cities, and made the land desolate, and the fullness of it, by the voice of his roaring."}}, {"v": 8, "ref": "19:8", "o": "וַ/יִּתְּנ֨וּ עָלָ֥י/ו גּוֹיִ֛ם סָבִ֖יב מִ/מְּדִינ֑וֹת וַֽ/יִּפְרְשׂ֥וּ עָלָ֛י/ו רִשְׁתָּ֖/ם בְּ/שַׁחְתָּ֥/ם נִתְפָּֽשׂ", "en": {"kjv": "Then the nations set against him on every side from the provinces, and spread their net over him: he was taken in their pit.", "web": "Then the nations set against him on every side from the provinces; and they spread their net over him; he was taken in their pit.", "bsb": "Then the nations set out against him from the provinces on every side. They spread their net over him; he was trapped in their pit.", "asv": "Then the nations set against him on every side from the provinces; and they spread their net over him; he was taken in their pit.", "ylt": "And set against it do nations Round about from the provinces. And they spread out for it their net, In their pit it hath been caught.", "dra": "And the nations came together against him on every side out of the provinces, and they spread their net over him, in their wounds he was taken.", "bbe": "Then the nations came against him from the kingdoms round about: their net was stretched over him and he was taken in the hole they had made.", "geneva": "Then the nations set against him on euery side of the countreys, and laide their nets for him: so he was taken in their pit.", "wycliffe": "And hethene men camen togidere ayens hym on ech side fro prouynces, and spredden on hym her net; he was takun in the woundis of tho hethene men.", "rotherham": "Then set upon him the nations round about. From the provinces,- And spread over him their net In their pit, was he caught;", "darby": "Then the nations set against him on every side from the provinces, and spread their net over him; he was taken in their pit.", "twenty": "", "jps": "Then the nations cried out against him on every side from the provinces; and they spread their net over him, he was taken in their pit.", "acv": "Then the nations set against him on every side from the provinces, and they spread their net over him. He was taken in their pit.", "anderson": "", "haweis": "", "noyes": "Then the nations set themselves against him on every side from the provinces, And spread their net over him; He was taken in their pit.", "webster": "Then the nations set against him on every side from the provinces, and spread their net over him: he was taken in their pit.", "vulgate": "et convenerunt adversum eum gentes undique de provinciis et expanderunt super eum rete suum in vulneribus earum captus est;", "brenton": "Then the nations set upon him from the countries round about, and they spread their nets upon him: he was taken in their pit."}}, {"v": 9, "ref": "19:9", "o": "וַֽ/יִּתְּנֻ֤/הוּ בַ/סּוּגַר֙ בַּֽ/חַחִ֔ים וַ/יְבִאֻ֖/הוּ אֶל מֶ֣לֶךְ בָּבֶ֑ל יְבִאֻ֨/הוּ֙ בַּ/מְּצֹד֔וֹת לְמַ֗עַן לֹא יִשָּׁמַ֥ע קוֹל֛/וֹ ע֖וֹד אֶל הָרֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And they put him in ward in chains, and brought him to the king of Babylon: they brought him into holds, that his voice should no more be heard upon the mountains of Israel.", "web": "They put him in a cage with hooks, and brought him to the king of Babylon; they brought him into strongholds, that his voice should no more be heard on the mountains of Israel.", "bsb": "With hooks they caged him and brought him to the king of Babylon. They brought him into captivity so that his roar was heard no longer on the mountains of Israel.", "asv": "And they put him in a cage with hooks, and brought him to the king of Babylon; they brought him into strongholds, that his voice should no more be heard upon the mountains of Israel.", "ylt": "And they put it in prison--in chains, And they bring it unto the king of Babylon, They bring it in unto bulwarks, So that its voice is not heard any more On mountains of Israel.", "dra": "And they put him into a cage, they brought him in chains to the king of Babylon: and they cast him into prison, that his voice should no more be heard upon the mountains of Israel.", "bbe": "They made him a prisoner with hooks, and took him to the king of Babylon; they put him in the strong place so that his voice might be sounding no longer on the mountains of Israel.", "geneva": "And they put him in prison and in chaines, and brought him to the King of Babel, and they put him in holdes, that his voyce should no more be heard vpon the mountaines of Israel.", "wycliffe": "And thei senten hym in to a caue in chaines, and brouyten hym to the kyng of Babiloyne; and thei senten hym in to prisoun, that his vois were no more herd on the hillis of Israel.", "rotherham": "And they put him in a cage with hooks, And brought him to Babylon’s king,— They brought him into strong-holds, That his noise might be heard no more Among the mountains of Israel.", "darby": "And they put him in a cage with nose-rings, and brought him to the king of Babylon; they brought him into strongholds, that his voice should no more be heard upon the mountains of Israel.", "twenty": "", "jps": "And they put him in a cage with hooks, and brought him to the king of Babylon; that they might bring him into strongholds, so that his voice should no more be heard upon the mountains of Israel.", "acv": "And they put him in a cage with hooks, and brought him to the king of Babylon. They brought him into strongholds, that his voice should no more be heard upon the mountains of Israel.", "anderson": "", "haweis": "", "noyes": "And they put him with nose rings into a cage, And carried him to the king of Babylon. And they carried him to a stronghold, That his voice might be heard no more Upon the mountains of Israel.", "webster": "And they put him in custody in chains, and brought him to the king of Babylon: they brought him into holds, that his voice should no more be heard upon the mountains of Israel.", "vulgate": "et miserunt eum in caveam in catenis adduxerunt eum ad regem Babylonis miseruntque eum in carcerem ne audiretur vox eius ultra super montes Israhel;", "brenton": "And they put him in chains and in a cage, and he came to the king of Babylon; and he cast him into prison, that his voice should not be heard on the mountains of Israel."}}, {"v": 10, "ref": "19:10", "o": "אִמְּ/ךָ֥ כַ/גֶּ֛פֶן בְּ/דָמְ/ךָ֖ עַל מַ֣יִם שְׁתוּלָ֑ה פֹּֽרִיָּה֙ וַֽ/עֲנֵפָ֔ה הָיְתָ֖ה מִ/מַּ֥יִם רַבִּֽים", "en": {"kjv": "Thy mother is like a vine in thy blood, planted by the waters: she was fruitful and full of branches by reason of many waters.", "web": "Your mother was like a vine, in your blood, planted by the waters: it was fruitful and full of branches by reason of many waters.", "bsb": "Your mother was like a vine in your vineyard, planted by the water; it was fruitful and full of branches because of the abundant waters.", "asv": "Thy mother was like a vine, in thy blood, planted by the waters: it was fruitful and full of branches by reason of many waters.", "ylt": "Thy mother is as a vine in thy blood by waters planted, Fruitful and full of boughs it hath been, Because of many waters.", "dra": "Thy mother is like a vine in thy blood planted by the water: her fruit and her branches have grown out of many waters.", "bbe": "Your mother was in comparison like a vine, planted by the waters: she was fertile and full of branches because of the great waters.", "geneva": "Thy mother is like a vine in thy blood, planted by the waters: she brought foorth fruite and branches by the abundant waters,", "wycliffe": "Thi modir as a vyner in thi blood was plauntid on watre; the fruitis therof and the boowis therof encreessiden of many watris.", "rotherham": "Thy mother [was] like a vine of thy vineyard, By waters, was planted,— Fruitful and full of branches, she became By reason of waters abundant;", "darby": "Thy mother was as a vine, in thy rest, planted by the waters: it was fruitful and full of branches by reason of many waters.", "twenty": "", "jps": "Thy mother was like a vine, in thy likeness, planted by the waters; she was fruitful and full of branches by reason of many waters.", "acv": "Thy mother was like a vine in thy blood, planted by the waters. It was fruitful and full of branches because of many waters.", "anderson": "", "haweis": "", "noyes": "Thy mother was like a vine planted like thyself by the waters; She was fruitful and full of branches by reason of many waters;", "webster": "Thy mother [is] like a vine in thy blood, planted by the waters: she was fruitful and full of branches by reason of many waters.", "vulgate": "mater tua quasi vinea in sanguine tuo super aquam plantata fructus eius et frondes eius creverunt ex aquis multis;", "brenton": "Thy mother was as a vine and as a blossom on a pomegranate tree, planted by water: her fruit and her shoot abounded by reason of much water."}}, {"v": 11, "ref": "19:11", "o": "וַ/יִּֽהְיוּ לָ֞/הּ מַטּ֣וֹת עֹ֗ז אֶל שִׁבְטֵי֙ מֹֽשְׁלִ֔ים וַ/תִּגְבַּ֥הּ קֽוֹמָת֖/וֹ עַל בֵּ֣ין עֲבֹתִ֑ים וַ/יֵּרָ֣א בְ/גָבְה֔/וֹ בְּ/רֹ֖ב דָּלִיֹּתָֽי/ו", "en": {"kjv": "And she had strong rods for the sceptres of them that bare rule, and her stature was exalted among the thick branches, and she appeared in her height with the multitude of her branches.", "web": "It had strong rods for the scepters of those who bore rule, and their stature was exalted among the thick boughs, and they were seen in their height with the multitude of their branches.", "bsb": "It had strong branches, fit for a ruler’s scepter. It towered high above the thick branches, conspicuous for its height and for its dense foliage.", "asv": "And it had strong rods for the sceptres of them that bare rule, and their stature was exalted among the thick boughs, and they were seen in their height with the multitude of their branches.", "ylt": "And it hath strong rods for sceptres of rulers, And high is its stature above thick branches, And it appeareth in its height In the multitude of its thin shoots.", "dra": "And she hath strong rods to make sceptres for them that bear rule, and her stature was exalted among the branches: and she saw her height in the multitude of her branches.", "bbe": "And she had a strong rod for a rod of authority for the rulers, and it became tall among the clouds and it was seen lifted up among the number of its branches.", "geneva": "And she had strong rods for the scepters of them that beare rule, and her stature was exalted among the branches, and she appeared in her height with the multitude of her branches.", "wycliffe": "And sadde yerdis weren maad to it in to septris of lordis, and the stature therof was enhaunsid among boowis; and it siy his hiynesse in the multitude of hise siouns.", "rotherham": "And they served her as staves of power For the sceptres of rulers, And high became the stature thereof With its interwoven foliage,- And it was seen by its height, By its multitude of branches.", "darby": "And it had strong rods for sceptres of them that bear rule, and its stature was exalted between the thick boughs; and it was conspicuous by its height with the multitude of its branches.", "twenty": "", "jps": "And she had strong rods to be sceptres for them that bore rule; and her stature was exalted among the thick branches, and she was seen in her height with the multitude of her tendrils.", "acv": "And it had strong twigs for the scepters of those who bore rule. And their stature was exalted among the thick boughs, and they were seen in their height with the multitude of their branches.", "anderson": "", "haweis": "", "noyes": "She had strong rods for sceptres of rulers, And her stature was high among the thick branches, So that she was conspicuous in her height, And the multitude of her branches.", "webster": "And she had strong rods for the scepters of them that bore rule, and her stature was exalted among the thick branches, and she appeared in her hight with the multitude of her branches.", "vulgate": "et factae sunt ei virgae solidae in sceptra dominantium et exaltata est statura eius inter frondes et vidit altitudinem suam in multitudine palmitum suorum;", "brenton": "And she became a rod for a tribe of princes, and was elevated in her bulk in the midst of other trees, and she saw her bulk in the multitude of her branches."}}, {"v": 12, "ref": "19:12", "o": "וַ/תֻּתַּ֤שׁ בְּ/חֵמָה֙ לָ/אָ֣רֶץ הֻשְׁלָ֔כָה וְ/ר֥וּחַ הַ/קָּדִ֖ים הוֹבִ֣ישׁ פִּרְיָ֑/הּ הִתְפָּרְק֧וּ וְ/יָבֵ֛שׁוּ מַטֵּ֥ה עֻזָּ֖/הּ אֵ֥שׁ אֲכָלָֽתְ/הוּ", "en": {"kjv": "But she was plucked up in fury, she was cast down to the ground, and the east wind dried up her fruit: her strong rods were broken and withered; the fire consumed them.", "web": "But it was plucked up in fury, it was cast down to the ground, and the east wind dried up its fruit: its strong rods were broken off and withered; the fire consumed them.", "bsb": "But it was uprooted in fury, cast down to the ground, and the east wind dried up its fruit. Its strong branches were stripped off and they withered; the fire consumed them.", "asv": "But it was plucked up in fury, it was cast down to the ground, and the east wind dried up its fruit: its strong rods were broken off and withered; the fire consumed them.", "ylt": "And it is plucked up in fury, To the earth it hath been cast, And the east wind hath dried up its fruit, Broken and withered hath been the rod of its strength, Fire hath consumed it.", "dra": "But she was plucked up in wrath, and cast on the ground, and the burning wind dried up her fruit: her strong rods are withered, and dried up: the fire hath devoured her.", "bbe": "But she was uprooted in burning wrath, and made low on the earth; the east wind came, drying her up, and her branches were broken off; her strong rod became dry, the fire made a meal of it.", "geneva": "But she was plucked vp in wrath: she was cast downe to the ground, and the East winde dried vp her fruite: her branches were broken, and withered: as for the rod of her strength, the fire consumed it.", "wycliffe": "And it was drawun out in wraththe, and was cast forth in to erthe; and a brennynge wynd dryede the fruyt therof, and the yerdis of strengthe therof welewiden, and weren maad drie, and fier eet it.", "rotherham": "Then was she uprooted in indignation To the ground, was she cast, And an east wind, dried up her fruit,—Broken off and withered were her staves of power, A fire, devoured them.", "darby": "But it was plucked up in fury, it was cast down to the ground, and the east wind dried up its fruit; its strong rods were broken and withered; the fire consumed them.", "twenty": "", "jps": "But she was plucked up in fury, she was cast down to the ground, and the east wind dried up her fruit; her strong rods were broken off and withered, the fire consumed her.", "acv": "But it was plucked up in fury. It was cast down to the ground, and the east wind dried up its fruit. Its strong twigs were broken off and withered. The fire consumed them.", "anderson": "", "haweis": "", "noyes": "But she was plucked up in fury, She was cast down to the ground, And the east wind dried up her fruit. Her strong rods were broken and withered; The fire consumed them.", "webster": "But she was plucked up in fury, she was cast down to the ground, and the east wind dried up her fruit: her strong rods were broken and withered; the fire consumed them.", "vulgate": "et evulsa est in ira in terramque proiecta et ventus urens siccavit fructum eius marcuerunt et arefactae sunt virgae roboris eius ignis comedit eam;", "brenton": "But she was broken down in wrath, she was cast upon the ground, and the east wind dried up her choice branches: vengeance came upon them, and the rod of her strength was withered; fire consumed it."}}, {"v": 13, "ref": "19:13", "o": "וְ/עַתָּ֖ה שְׁתוּלָ֣ה בַ/מִּדְבָּ֑ר בְּ/אֶ֖רֶץ צִיָּ֥ה וְ/צָמָֽא", "en": {"kjv": "And now she is planted in the wilderness, in a dry and thirsty ground.", "web": "Now it is planted in the wilderness, in a dry and thirsty land.", "bsb": "Now it is planted in the wilderness, in a dry and thirsty land.", "asv": "And now it is planted in the wilderness, in a dry and thirsty land.", "ylt": "And now--it is planted in a wilderness, In a land dry and thirsty.", "dra": "And now she is transplanted into the desert, in a land not passable, and dry.", "bbe": "And now she is planted in the waste land, in a dry and unwatered country.", "geneva": "And now she is planted in the wildernes in a drie and thirstie ground.", "wycliffe": "And now it is plauntid ouer in desert, in a lond with out weie, and thristi.", "rotherham": "Now, therefore, is she planted in a desert, -In a land parched and dry;", "darby": "And now it is planted in the wilderness, in a dry and thirsty ground:", "twenty": "", "jps": "And now she is planted in the wilderness, in a dry and thirsty ground.", "acv": "And now it is planted in the wilderness, in a dry and thirsty land.", "anderson": "", "haweis": "", "noyes": "And now she is planted in the desert, In a dry and thirsty land.", "webster": "And now she [is] planted in the wilderness, in a dry and thirsty ground.", "vulgate": "et nunc transplantata est in desertum in terra invia et sitienti;", "brenton": "And now they have planted her in the wilderness, in a dry land."}}, {"v": 14, "ref": "19:14", "o": "וַ/תֵּצֵ֨א אֵ֜שׁ מִ/מַּטֵּ֤ה בַדֶּ֨י/הָ֙ פִּרְיָ֣/הּ אָכָ֔לָה וְ/לֹא הָ֥יָה בָ֛/הּ מַטֵּה עֹ֖ז שֵׁ֣בֶט לִ/מְשׁ֑וֹל קִ֥ינָה הִ֖יא וַ/תְּהִ֥י לְ/קִינָֽה", "en": {"kjv": "And fire is gone out of a rod of her branches, which hath devoured her fruit, so that she hath no strong rod to be a sceptre to rule. This is a lamentation, and shall be for a lamentation.", "web": "Fire is gone out of the rods of its branches, it has devoured its fruit, so that there is in it no strong rod to be a scepter to rule. This is a lamentation, and shall be for a lamentation.", "bsb": "Fire has gone out from its main branch and devoured its fruit; on it no strong branch remains fit for a ruler’s scepter.’ This is a lament and shall be used as a lament.”", "asv": "And fire is gone out of the rods of its branches, it hath devoured its fruit, so that there is in it no strong rod to be a sceptre to rule. This is a lamentation, and shall be for a lamentation.", "ylt": "And go forth doth fire from a rod of its boughs, Its fruit it hath devoured, And it hath no rod of strength--a sceptre to rule, Lamentation it is --and it is for a lamentation!'", "dra": "And a fire is gone out from a rod of her branches, which hath devoured her fruit: so that she now hath no strong rod, to be a sceptre of rulers. This is a lamentation, and it shall be for a lamentation.", "bbe": "And fire has gone out from her rod, causing the destruction of her branches, so that there is no strong rod in her to be the ruler's rod of authority. This is a song of grief, and it was for a song of grief.", "geneva": "And fire is gone out of a rod of her branches, which hath deuoured her fruite, so that she hath no strong rod to be a scepter to rule: this is a lamentation and shalbe for a lamentation.", "wycliffe": "And fier yede out of the yerde of the braunchis therof, that eet the fruyt therof. And a stronge yerde, the ceptre of lordis, was not in it. It is weilyng, and it schal be in to weilyng.", "rotherham": "And there hath gone forth a fire out of her staves of rods. Her fruit, hath it devoured, And there is in her no staff of power. As a sceptre to bear rule. A dirge, it is, and hath been made a dirge.", "darby": "and a fire is gone out of a rod of its branches, [which] hath devoured its fruit; so that it hath no strong rod to be a sceptre for ruling. This is a lamentation, and shall be for a lamentation.", "twenty": "", "jps": "And fire is gone out of the rod of her branches, it hath devoured her fruit, so that there is in her no strong rod to be a sceptre to rule.' This is a lamentation, and it was for a lamentation.", "acv": "And fire has gone out of the twigs of its branches. It has devoured its fruit, so that there is no strong twig in it to be a scepter to rule. This is a lamentation, and shall be for a lamentation.", "anderson": "", "haweis": "", "noyes": "And a fire is gone forth out of a rod of her branches, Which hath devoured her fruit, So that she hath no strong rod for a ruler’s sceptre. This is a lamentation, and it shall be for a lamentation.", "webster": "And fire hath gone out of a rod of her branches, [which] hath devoured her fruit, so that she hath no strong rod [to be] a scepter to rule. This [is] a lamentation, and shall be for a lamentation.", "vulgate": "et egressus est ignis de virga ramorum eius qui fructum eius comedit et non fuit in ea virga fortis sceptrum dominantium planctus est et erit in planctum;", "brenton": "And fire is gone out of a rod of her choice boughs, and has devoured her; and there was no rod of strength in her. Her race is become a parable of lamentation, and it shall be for a lamentation."}}]}, {"c": 20, "verses": [{"v": 1, "ref": "20:1", "o": "וַ/יְהִ֣י בַּ/שָּׁנָ֣ה הַ/שְּׁבִיעִ֗ית בַּֽ/חֲמִשִׁי֙ בֶּ/עָשׂ֣וֹר לַ/חֹ֔דֶשׁ בָּ֧אוּ אֲנָשִׁ֛ים מִ/זִּקְנֵ֥י יִשְׂרָאֵ֖ל לִ/דְרֹ֣שׁ אֶת יְהוָ֑ה וַ/יֵּשְׁב֖וּ לְ/פָנָֽ/י", "en": {"kjv": "And it came to pass in the seventh year, in the fifth month, the tenth day of the month, that certain of the elders of Israel came to enquire of the Lord, and sat before me.", "web": "In the seventh year, in the fifth month, the tenth day of the month, some of the elders of Israel came to inquire of Yahweh, and sat before me.", "bsb": "In the seventh year, on the tenth day of the fifth month, some of the elders of Israel came to inquire of the LORD, and they sat down before me.", "asv": "And it came to pass in the seventh year, in the fifthmonth, the tenthdayof the month, that certain of the elders of Israel came to inquire of Jehovah, and sat before me.", "ylt": "And it cometh to pass, in the seventh year, in the fifth month , in the tenth of the month, come in have certain of the elders of Israel to seek Jehovah, and they sit before me;", "dra": "And it came to pass in the seventh year, in the fifth month, the tenth day of the month: there came men of the ancients of Israel to inquire of the Lord, and they sat before me.", "bbe": "Now it came about in the seventh year, in the fifth month, on the tenth day of the month, that certain of the responsible men of Israel came to get directions from the Lord and were seated before me.", "geneva": "And in the seuenth yeere, in the fift moneth, the tenth day of the moneth, came certaine of the elders of Israel to enquire of the Lord, and sate before me.", "wycliffe": "And it was doon in the seuenthe yeer, in the fyuethe monethe, in the tenthe dai of the monethe, men of the eldris of Israel camen to axe the Lord; and thei saten bifor me.", "rotherham": "And it came to pass in the seventh year in the fifth month, on the tent of the month, that there came in men of the elders of Israel to enquire of Yahweh,—and they sat before me.", "darby": "And it came to pass in the seventh year, in the fifth [month], the tenth of the month, [that] certain of the elders of Israel came to inquire of Jehovah, and they sat before me.", "twenty": "", "jps": "And it came to pass in the seventh year, in the fifth month, the tenth day of the month, that certain of the elders of Israel came to inquire of HaShem, and sat before me.", "acv": "And it came to pass in the seventh year, in the fifth month, the tenth day of the month, that certain of the elders of Israel came to inquire of Jehovah, and sat before me.", "anderson": "", "haweis": "", "noyes": "And it came to pass in the seventh year, in the fifth month, on the tenth day of the month, that certain of the elders of Israel came to inquire of Jehovah, and sat before me.", "webster": "And it came to pass in the seventh year, in the fifth [month], the tenth [day] of the month, [that] certain of the elders of Israel came to inquire of the LORD, and sat before me.", "vulgate": "et factum est in anno septimo in quinto mense in decima mensis venerunt viri de senioribus Israhel ut interrogarent Dominum et sederunt coram me;", "brenton": "And it came to pass in the seventh year, on the fifteenth day of the month, there came men of the elders of the house of Israel to enquire of the Lord, and they sat before me."}}, {"v": 2, "ref": "20:2", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Then came the word of the Lord unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "and there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Then came the worde of the Lord vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me saying:-", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Then came the word of Jehovah to me, saying:", "webster": "Then came the word of the LORD to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 3, "ref": "20:3", "o": "בֶּן אָדָ֗ם דַּבֵּ֞ר אֶת זִקְנֵ֤י יִשְׂרָאֵל֙ וְ/אָמַרְתָּ֣ אֲלֵ/הֶ֔ם כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הֲ/לִ/דְרֹ֥שׁ אֹתִ֖/י אַתֶּ֣ם בָּאִ֑ים חַי אָ֨נִי֙ אִם אִדָּרֵ֣שׁ לָ/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Son of man, speak unto the elders of Israel, and say unto them, Thus saith the Lord God; Are ye come to enquire of me? As I live, saith the Lord God, I will not be enquired of by you.", "web": "Son of man, speak to the elders of Israel, and tell them, Thus says the Lord Yahweh: Is it to inquire of me that you have come? As I live, says the Lord Yahweh, I will not be inquired of by you.", "bsb": "“Son of man, speak to the elders of Israel and tell them that this is what the Lord GOD says: Have you come to inquire of Me? As surely as I live, I will not be consulted by you, declares the Lord GOD.", "asv": "Son of man, speak unto the elders of Israel, and say unto them, Thus saith the Lord Jehovah: Is it to inquire of me that ye are come? As I live, saith the Lord Jehovah, I will not be inquired of by you.", "ylt": "`Son of man, speak with the elders of Israel, and thou hast said unto them, Thus said the Lord Jehovah: To seek Me are ye coming in? I live--I am not sought by you--an affirmation of the Lord Jehovah.", "dra": "Son of man, speak to the ancients of Israel and say to them: Thus saith the Lord God: Are you come to inquire of me? As I live, I will not answer you, saith the Lord God.", "bbe": "Son of man, say to the responsible men of Israel, This is what the Lord has said: Have you come to get directions from me? By my life, says the Lord, you will get no directions from me.", "geneva": "Sonne of man, speake vnto the Elders of Israel, and say vnto them, Thus saith the Lord God, Are ye come to enquire of me? as I liue, sayth the Lord God, when I am asked, I wil not answer you.", "wycliffe": "and he seide, Sone of man, speke thou to the eldere men of Israel; and thou schalt seie to hem, The Lord God seith these thingis, Whether ye camen to axe me? Y lyue, for Y schal not answere to you, seith the Lord God. Sone of man,", "rotherham": "Son of man Speak thou with the elders of Israel and say unto them, Thus, saith My Lord Yahweh, To enquire of me, are ye coming in? As I live, verily I will not be enquired of by you, Declareth My Lord Yahweh.", "darby": "Son of man, speak unto the elders of Israel, and say unto them, Thus saith the Lord Jehovah: Are ye come to inquire of me? [As] I live, saith the Lord Jehovah, I will not be inquired of by you.", "twenty": "", "jps": "'Son of man, speak unto the elders of Israel, and say unto them: Thus saith the L-rd GOD: Are ye come to inquire of Me? As I live, saith the L-rd GOD, I will not be inquired of by you.", "acv": "Son of man, speak to the elders of Israel, and say to them, Thus says the lord Jehovah: Is it to inquire of me that ye have come? As I live, says the lord Jehovah, I will not be inquired of by you.", "anderson": "", "haweis": "", "noyes": "Son of man, speak to the elders of Israel, and say to them, Thus saith the Lord Jehovah: Are ye come to inquire of me? As I live, saith the Lord Jehovah, I will not be inquired of by you.", "webster": "Son of man, speak to the elders of Israel, and say to them, Thus saith the Lord GOD; Are ye come to inquire of me? [As] I live, saith the Lord GOD, I will not be inquired of by you.", "vulgate": "fili hominis loquere senioribus Israhel et dices ad eos haec dicit Dominus Deus num ad interrogandum me vos venistis vivo ego quia non respondebo vobis ait Dominus Deus;", "brenton": "Son of man, speak to the elders of the house of Israel, and thou shalt say to them, Thus saith the Lord; Are ye come to enquire of me? As I live, I will not be enquired of by you, saith the Lord."}}, {"v": 4, "ref": "20:4", "o": "הֲ/תִשְׁפֹּ֣ט אֹתָ֔/ם הֲ/תִשְׁפּ֖וֹט בֶּן אָדָ֑ם אֶת תּוֹעֲבֹ֥ת אֲבוֹתָ֖/ם הוֹדִיעֵֽ/ם", "en": {"kjv": "Wilt thou judge them, son of man, wilt thou judge them? cause them to know the abominations of their fathers:", "web": "Will you judge them, son of man, will you judge them? Cause them to know the abominations of their fathers;", "bsb": "Will you judge them, will you judge them, son of man? Confront them with the abominations of their fathers", "asv": "Wilt thou judge them, son of man, wilt thou judge them? Cause them to know the abominations of their fathers;", "ylt": "Dost thou judge them? Dost thou judge, son of man? The abominations of their fathers cause them to know,", "dra": "If thou judgest them, if thou judgest, O son of man, declare to them the abominations of their fathers.", "bbe": "Will you be their judge, O son of man, will you be their judge? make clear to them the disgusting ways of their fathers,", "geneva": "Wilt thou iudge them, sonne of man? wilt thou iudge them? cause them to vnderstand the abominations of their fathers,", "wycliffe": "if thou demest hem, if thou demest, schewe thou to hem the abhomynaciouns of her fadris.", "rotherham": "Wilt thou judge them, wilt thou judge, O son of man? The abominations of their fathers, let them know:", "darby": "Wilt thou judge them, wilt thou judge, son of man? Cause them to know the abominations of their fathers,", "twenty": "", "jps": "Wilt thou judge them, son of man, wilt thou judge them? cause them to know the abominations of their fathers;", "acv": "Will thou judge them, son of man, will thou judge them? Cause them to know the abominations of their fathers,", "anderson": "", "haweis": "", "noyes": "Punish them, punish them, son of man, cause them to know the abominations of their fathers, and say to them,", "webster": "Wilt thou judge them, son of man, wilt thou judge [them]? cause them to know the abominations of their fathers:", "vulgate": "si iudicas eos si iudicas fili hominis abominationes patrum eorum ostende eis;", "brenton": "Shall I utterly take vengeance on them, son of man? testify to them of the iniquities of their fathers:"}}, {"v": 5, "ref": "20:5", "o": "וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֗ם כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ בְּ/יוֹם֙ בָּחֳרִ֣/י בְ/יִשְׂרָאֵ֔ל וָ/אֶשָּׂ֣א יָדִ֗/י לְ/זֶ֨רַע֙ בֵּ֣ית יַֽעֲקֹ֔ב וָ/אִוָּדַ֥ע לָ/הֶ֖ם בְּ/אֶ֣רֶץ מִצְרָ֑יִם וָ/אֶשָּׂ֨א יָדִ֤/י לָ/הֶם֙ לֵ/אמֹ֔ר אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And say unto them, Thus saith the Lord God; In the day when I chose Israel, and lifted up mine hand unto the seed of the house of Jacob, and made myself known unto them in the land of Egypt, when I lifted up mine hand unto them, saying, I am the Lord your God;", "web": "and tell them, Thus says the Lord Yahweh: In the day when I chose Israel, and swore to the seed of the house of Jacob, and made myself known to them in the land of Egypt, when I swore to them, saying, I am Yahweh your God;", "bsb": "and tell them that this is what the Lord GOD says: On the day I chose Israel, I swore an oath to the descendants of the house of Jacob and made Myself known to them in the land of Egypt. With an uplifted hand I said to them, ‘I am the LORD your God.’", "asv": "and say unto them, Thus saith the Lord Jehovah: In the day when I chose Israel, and sware unto the seed of the house of Jacob, and made myself known unto them in the land of Egypt, when I sware unto them, saying, I am Jehovah your God;", "ylt": "and thou hast said unto them: Thus said the Lord Jehovah: In the day of My fixing on Israel, I lift up My hand, To the seed of the house of Jacob, And am known to them in the land of Egypt, And I lift up My hand to them, Saying, I am Jehovah your God.", "dra": "And say to them: Thus saith the Lord God: In the day when I chose Israel, and lifted up my hand for the race of the house of Jacob: and appeared to them in the land of Egypt, and lifted up my hand for them, saying: I am the Lord your God:", "bbe": "And say to them, This is what the Lord has said: In the day when I took Israel for myself, when I made an oath to the seed of the family of Jacob, and I gave them knowledge of myself in the land of Egypt, saying to them with an oath, I am the Lord your God;", "geneva": "And say vnto them, Thus saith the Lord God, In the day when I chose Israel, and lift vp mine hand vnto the seede of the house of Iaakob, and made my selfe knowen vnto them in the land of Egypt, when I lift vp mine hand vnto them, and sayd, I am the Lord your God,", "wycliffe": "And thou schalt seie to hem, The Lord God seith these thingis, In the dai in which Y chees Israel, and reiside myn hond for the generacioun of the hous of Jacob, and Y apperide to hem in the lond of Egipt, and Y reiside myn hond for hem, and Y seide, Y am youre Lord God,", "rotherham": "So then thou shalt say unto them Thus, saith My Lord Yahweh, In the day when I made choice of Israel, then lifted I up my hand. to the seed of the house of Jacob, and made myself known to them, in the land of Egypt,- Yea I lifted up my hand to them, saying, I Yahweh, am your God.", "darby": "and say unto them, Thus saith the Lord Jehovah: In the day when I chose Israel, and lifted up my hand unto the seed of the house of Jacob, and made myself known unto them in the land of Egypt, when I lifted up my hand unto them, saying, I [am] Jehovah yourGod,", "twenty": "", "jps": "and say unto them: Thus saith the L-rd GOD: In the day when I chose Israel, and lifted up My hand unto the seed of the house of Jacob, and made Myself known unto them in the land of Egypt, when I lifted up My hand unto them, saying: I am HaShem your G-d;", "acv": "and say to them, Thus says the lord Jehovah: In the day when I chose Israel, and swore to the seed of the house of Jacob, and made myself known to them in the land of Egypt, when I swore to them, saying, I am Jehovah your God,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: At the time when I chose Israel, I lifted up my hand to the race of the house of Jacob, and made myself known to them in the land of Egypt; I lifted up my hand to them, and said, I am Jehovah, your God.", "webster": "And say to them, Thus saith the Lord GOD; In the day when I chose Israel, and lifted up my hand to the seed of the house of Jacob, and made myself known to them in the land of Egypt, when I lifted up my hand to them, saying, I [am] the LORD your God;", "vulgate": "et dices ad eos haec dicit Dominus Deus in die qua elegi Israhel et levavi manum meam pro stirpe domus Iacob et apparui eis in terra Aegypti et levavi manum meam pro eis dicens ego Dominus Deus vester;", "brenton": "and thou shalt say to them, Thus saith the Lord; From the day that I chose the house of Israel, and became known to the seed of the house of Jacob, and was known to them in the land of Egypt, and helped them with my hand, saying, I am the Lord your God;"}}, {"v": 6, "ref": "20:6", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא נָשָׂ֤אתִי יָדִ/י֙ לָ/הֶ֔ם לְ/הֽוֹצִיאָ֖/ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם אֶל אֶ֜רֶץ אֲשֶׁר תַּ֣רְתִּי לָ/הֶ֗ם זָבַ֤ת חָלָב֙ וּ/דְבַ֔שׁ צְבִ֥י הִ֖יא לְ/כָל הָ/אֲרָצֽוֹת", "en": {"kjv": "In the day that I lifted up mine hand unto them, to bring them forth of the land of Egypt into a land that I had espied for them, flowing with milk and honey, which is the glory of all lands:", "web": "in that day I swore to them, to bring them out of the land of Egypt into a land that I had searched out for them, flowing with milk and honey, which is the glory of all lands.", "bsb": "On that day I swore to bring them out of the land of Egypt into a land that I had searched out for them, a land flowing with milk and honey, the glory of all lands.", "asv": "in that day I sware unto them, to bring them forth out of the land of Egypt into a land that I had searched out for them, flowing with milk and honey, which is the glory of all lands.", "ylt": "In that day I did lift up My hand to them, To bring them forth from the land of Egypt, Unto a land that I spied out for them, Flowing with milk and honey, A beauty it is to all the lands,", "dra": "In that day I lifted up my hand for them to bring them out of the land of Egypt, into a land which I had provided for them, flowing with milk and honey, which excelled amongst all lands.", "bbe": "In that day I gave my oath to take them out of the land of Egypt into a land which I had been searching out for them, a land flowing with milk and honey, the glory of all lands:", "geneva": "In the day that I lift vp mine hand vnto them to bring them forth of the land of Egypt, into a land that I had prouided for them, flowing with milke and hony which is pleasant among all lands,", "wycliffe": "in that dai Y reiside myn hond for hem, that Y schulde leede hem out of the lond of Egipt, in to the lond which Y hadde purueiede to hem, the lond flowynge with mylk and hony, which is noble among alle londis.", "rotherham": "In that day, lifted I up my hand to them, to bring them forth out of the land of Egypt,—into a land that I had looked out for them flowing with milk and honey, The beauty, it was of all lands,", "darby": "in that day I lifted up my hand unto them, to bring them out of the land of Egypt into a land that I had espied for them, flowing with milk and honey, which is the ornament of all lands;", "twenty": "", "jps": "in that day I lifted up My hand unto them, to bring them forth out of the land of Egypt into a land that I had sought out for them, flowing with milk and honey, which is the beauty of all lands;", "acv": "I swore to them in that day, to bring them forth out of the land of Egypt into a land that I had searched out for them, flowing with milk and honey, which is the glory of all lands.", "anderson": "", "haweis": "", "noyes": "At that time I lifted up my hand to them, that I would bring them forth out of the land of Egypt, into a land which I had looked out for them, flowing with milk and honey, the glory of all lands.", "webster": "In the day [that] I lifted up my hand to them, to bring them forth from the land of Egypt into a land that I had espied for them, flowing with milk and honey, which [is] the glory of all lands:", "vulgate": "in die illa levavi manum meam pro eis ut educerem eos de terra Aegypti in terram quam provideram eis fluentem lacte et melle quae est egregia inter omnes terras;", "brenton": "in that day I helped them with my hand, to bring them out of the land of Egypt into the land which I prepared for them, a land flowing with milk and honey, it is abundant beyond every land."}}, {"v": 7, "ref": "20:7", "o": "וָ/אֹמַ֣ר אֲלֵ/הֶ֗ם אִ֣ישׁ שִׁקּוּצֵ֤י עֵינָי/ו֙ הַשְׁלִ֔יכוּ וּ/בְ/גִלּוּלֵ֥י מִצְרַ֖יִם אַל תִּטַּמָּ֑אוּ אֲנִ֖י יְהוָ֥ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "Then said I unto them, Cast ye away every man the abominations of his eyes, and defile not yourselves with the idols of Egypt: I am the Lord your God.", "web": "I said to them, Cast away every man the abominations of his eyes, and don’t defile yourselves with the idols of Egypt; I am Yahweh your God.", "bsb": "And I said to them: ‘Each of you must throw away the abominations before his eyes, and you must not defile yourselves with the idols of Egypt. I am the LORD your God.’", "asv": "And I said unto them, Cast ye away every man the abominations of his eyes, and defile not yourselves with the idols of Egypt; I am Jehovah your God.", "ylt": "And I say unto them, Let each cast away the detestable things of his eyes, And with the idols of Egypt be not defiled, I am Jehovah your God.", "dra": "And I said to them: Let every man cast away the scandals of his eyes, and defile not yourselves with the idols of Egypt: I am the Lord your God.", "bbe": "And I said to them, Let every man among you put away the disgusting things to which his eyes are turned, and do not make yourselves unclean with the images of Egypt; I am the Lord your God.", "geneva": "Then sayd I vnto them, Let euery man cast away the abominations of his eyes, and defile not your selues with the idols of Egypt: for I am the Lord your God.", "wycliffe": "And Y seide to hem, Ech man caste awei the offenciouns of hise iyen, and nyle ye be defoulid in the idols of Egipt; Y am youre Lord God.", "rotherham": "And I said unto them. Every one the abomination of his eyes, cast ye away, And with the manufactured gods of Egypt, let it not be that ye defile yourselves: I, Yahweh, am your God.", "darby": "and I said unto them, Cast ye away every man the abominations of his eyes, and defile not yourselves with the idols of Egypt: I [am] Jehovah yourGod.", "twenty": "", "jps": "and I said unto them: Cast ye away every man the detestable things of his eyes, and defile not yourselves with the idols of Egypt; I am HaShem your G-d.", "acv": "And I said to them, Cast ye away every man the abominations of his eyes, and do not defile yourselves with the idols of Egypt. I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "And I said to them, Cast ye away from you every one the abomination of his eyes, and defile not yourselves with the idols of Egypt! I am Jehovah, your God.", "webster": "Then said I to them, Cast ye away every man the abominations of his eyes, and defile not yourselves with the idols of Egypt: I [am] the LORD your God.", "vulgate": "et dixi ad eos unusquisque offensiones oculorum suorum abiciat et in idolis Aegypti nolite pollui ego Dominus Deus vester;", "brenton": "And I said to them, Let every one cast away the abominations of his eyes, and defile not yourselves with the devices of Egypt: I am the Lord your God."}}, {"v": 8, "ref": "20:8", "o": "וַ/יַּמְרוּ בִ֗/י וְ/לֹ֤א אָבוּ֙ לִּ/שְׁמֹ֣עַ אֵלַ֔/י אִ֣ישׁ אֶת שִׁקּוּצֵ֤י עֵֽינֵי/הֶם֙ לֹ֣א הִשְׁלִ֔יכוּ וְ/אֶת גִּלּוּלֵ֥י מִצְרַ֖יִם לֹ֣א עָזָ֑בוּ וָ/אֹמַ֞ר לִ/שְׁפֹּ֧ךְ חֲמָתִ֣/י עֲלֵי/הֶ֗ם לְ/כַלּ֤וֹת אַפִּ/י֙ בָּ/הֶ֔ם בְּ/ת֖וֹךְ אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "But they rebelled against me, and would not hearken unto me: they did not every man cast away the abominations of their eyes, neither did they forsake the idols of Egypt: then I said, I will pour out my fury upon them, to accomplish my anger against them in the midst of the land of Egypt.", "web": "But they rebelled against me, and would not listen to me; they each didn’t throw away the abominations of their eyes, neither did they forsake the idols of Egypt. Then I said I would pour out my wrath on them, to accomplish my anger against them in the midst of the land of Egypt.", "bsb": "But they rebelled against Me and refused to listen. None of them cast away the abominations before their eyes, and they did not forsake the idols of Egypt. So I resolved to pour out My wrath upon them and vent My anger against them in the land of Egypt.", "asv": "But they rebelled against me, and would not hearken unto me; they did not every man cast away the abominations of their eyes, neither did they forsake the idols of Egypt. Then I said I would pour out my wrath upon them, to accomplish my anger against them in the midst of the land of Egypt.", "ylt": "And--they rebel against Me, And have not been willing to hearken to Me, Each, the detestable things of their eyes, They have not cast away, And the idols of Egypt have not forsaken, And I say--to pour out My fury on them, To complete Mine anger against them, In the midst of the land of Egypt.", "dra": "But they provoked me, and would not hearken to me: they did not every man cast away the abominations of his eyes, neither did they forsake the idols of Egypt: and I said I would pour out my indignation upon them, and accomplish my wrath against them in the midst of the land of Egypt.", "bbe": "But they would not be controlled by me, and did not give ear to me; they did not put away the disgusting things to which their eyes were turned, or give up the images of Egypt: then I said I would let loose my passion on them to give full effect to my wrath against them in the land of Egypt.", "geneva": "But they rebelled against me, and would not heare me: for none cast away the abominations of their eyes, neither did they forsake the idoles of Egypt: then I thought to powre out mine indignation vpon them, and to accomplish my wrath against them in the mids of the land of Egypt.", "wycliffe": "And thei terriden me to wraththe, and nolden here me; ech man castide not awei the abhomynaciouns of hise iyen, nether thei forsoken the idols of Egipt.", "rotherham": "But they rebelled against me And were not willing to hearken unto me, Every man the abominations of their eyes, they cast not away, And the manufactured gods of Egypt, forsook they not; Therefore spake I of pouring out mine indignation upon them to bring mine anger to an end against them, in the midst of the land of Egypt.", "darby": "But they rebelled against me, and would not hearken unto me: none of them cast away the abominations of his eyes, neither did they forsake the idols of Egypt. Then I thought to pour out my fury upon them, so as to accomplish mine anger against them in the midst of the land of Egypt.", "twenty": "", "jps": "But they rebelled against Me, and would not hearken unto Me; they did not every man cast away the detestable things of their eyes, neither did they forsake the idols of Egypt; then I said I would pour out My fury upon them, to spend My anger upon them in the midst of the land of Egypt.", "acv": "But they rebelled against me, and would not hearken to me. They did not every man cast away the abominations of their eyes, nor did they forsake the idols of Egypt. Then I said I would pour out my wrath upon them, to accomplish my anger against them in the midst of the land of Egypt.", "anderson": "", "haweis": "", "noyes": "But they rebelled against me, and would not hearken to me; they did not cast away every one the abominations of his eyes, neither did they forsake the idols of Egypt. Then I said that I would pour out my fury upon them, that I would accomplish mine anger against them in the midst of the land of Egypt.", "webster": "But they rebelled against me, and would not hearken to me: they did not every man cast away the abominations of their eyes, neither did they forsake the idols of Egypt: then I said, I will pour out my fury upon them, to accomplish my anger against them in the midst of the land of Egypt.", "vulgate": "et inritaverunt me nolueruntque audire unusquisque abominationes oculorum suorum non proiecit nec idola Aegypti reliquerunt et dixi ut effunderem indignationem meam super eos et implerem iram meam in eis in medio terrae Aegypti;", "brenton": "But they revolted from me, and would not hearken to me: they cast not away the abominations of their eyes, and forsook not the devices of Egypt: then I said that I would pour out my wrath upon them, to accomplish my wrath upon them in the midst of Egypt."}}, {"v": 9, "ref": "20:9", "o": "וָ/אַ֨עַשׂ֙ לְמַ֣עַן שְׁמִ֔/י לְ/בִלְתִּ֥י הֵחֵ֛ל לְ/עֵינֵ֥י הַ/גּוֹיִ֖ם אֲשֶׁר הֵ֣מָּה בְ/תוֹכָ֑/ם אֲשֶׁ֨ר נוֹדַ֤עְתִּי אֲלֵי/הֶם֙ לְ/עֵ֣ינֵי/הֶ֔ם לְ/הוֹצִיאָ֖/ם מֵ/אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "But I wrought for my name’s sake, that it should not be polluted before the heathen, among whom they were, in whose sight I made myself known unto them, in bringing them forth out of the land of Egypt.", "web": "But I worked for my name’s sake, that it should not be profaned in the sight of the nations, among which they were, in whose sight I made myself known to them, in bringing them out of the land of Egypt.", "bsb": "But I acted for the sake of My name, that it should not be profaned in the eyes of the nations among whom they were living, in whose sight I had revealed Myself to Israel by bringing them out of the land of Egypt.", "asv": "But I wrought for my name’s sake, that it should not be profaned in the sight of the nations, among which they were, in whose sight I made myself known unto them, in bringing them forth out of the land of Egypt.", "ylt": "And I do it for My name's sake, Not to pollute it before the eyes of the nations, In whose midst they are , Before whose eyes I became known to them, To bring them out from the land of Egypt.", "dra": "But I did otherwise for my name's sake, that it might not be violated before the nations, in the midst of whom they were, and among whom I made myself known to them, to bring them out of the land of Egypt.", "bbe": "And I was acting for the honour of my name, so that it might not be made unclean before the eyes of the nations among whom they were, and before whose eyes I gave them knowledge of myself, by taking them out of the land of Egypt.", "geneva": "But I had respect to my Name, that it should not be polluted before the heathen, among whome they were, and in whose sight I made my selfe knowen vnto them in bringing them forth of the land of Egypt.", "wycliffe": "And Y seide, that Y wold schede out myn indignacioun on hem, and fille my wraththe in hem, in the myddis of the lond of Egipt. And Y dide for my name, that it schulde not be defoulid bifore hethene men, in the myddis of whiche thei weren, and among whiche Y apperide to hem, that Y schulde lede hem out of the lond of Egipt.", "rotherham": "Howbeit I wrought with effect, for the sake of mine own Name, that it might not be profaned—before the eyes of the nations in whose midst they were,—before whose eyes I made myself known unto them, by bringing them forth out of the land of Egypt.", "darby": "But I wrought for my name's sake, that it should not be profaned in the sight of the nations among whom they were, in whose sight I had made myself known unto them in bringing them forth out of the land of Egypt.", "twenty": "", "jps": "But I wrought for My name's sake, that it should not be profaned in the sight of the nations, among whom they were, in whose sight I made Myself known unto them, so as to bring them forth out of the land of Egypt.", "acv": "But I worked for my name's sake (that it should not be profaned in the sight of the nations, among which they were, in whose sight I made myself known to them) in bringing them forth out of the land of Egypt.", "anderson": "", "haweis": "", "noyes": "But I acted for my name’s sake, that it might not be polluted in the sight of the nations, in the midst of whom they were; and before their eyes I made myself known to them, in bringing them forth out of the land of Egypt.", "webster": "But I wrought for my name's sake, that it should not be profaned before the heathen, among whom they [were], in whose sight I made myself known to them, in bringing them forth from the land of Egypt.", "vulgate": "et feci propter nomen meum ut non violaretur coram gentibus in quarum medio erant et inter quas apparui eis ut educerem eos de terra Aegypti;", "brenton": "But I wrought so that my name should not be at all profaned in the sight of the Gentiles, in the midst of whom they are, among whom I was made known to them in their sight, to bring them out of the land of Egypt."}}, {"v": 10, "ref": "20:10", "o": "וָ/אֽוֹצִיאֵ֖/ם מֵ/אֶ֣רֶץ מִצְרָ֑יִם וָ/אֲבִאֵ֖/ם אֶל הַ/מִּדְבָּֽר", "en": {"kjv": "Wherefore I caused them to go forth out of the land of Egypt, and brought them into the wilderness.", "web": "So I caused them to go out of the land of Egypt, and brought them into the wilderness.", "bsb": "So I brought them out of the land of Egypt and led them into the wilderness.", "asv": "So I caused them to go forth out of the land of Egypt, and brought them into the wilderness.", "ylt": "And I bring them out of the land of Egypt, And I bring them in unto the wilderness,", "dra": "Therefore I brought them out from the land of Egypt, and brought them into the desert.", "bbe": "So I made them go out of the land of Egypt and took them into the waste land.", "geneva": "Nowe I caried them out of the land of Egypt, and brought them into the wildernes.", "wycliffe": "Therfor Y castide hem out of the lond of Egipt, and Y ledde hem out in to desert;", "rotherham": "Therefore brought I them forth out of the land of Egypt,—and caused them to come into the desert.", "darby": "And I caused them to go forth out of the land of Egypt, and brought them into the wilderness.", "twenty": "", "jps": "So I caused them to go forth out of the land of Egypt, and brought them into the wilderness.", "acv": "So I caused them to go forth out of the land of Egypt, and brought them into the wilderness.", "anderson": "", "haweis": "", "noyes": "And I brought them forth out of the land of Egypt, and led them into the wilderness.", "webster": "Wherefore I caused them to go forth from the land of Egypt, and brought them into the wilderness.", "vulgate": "eieci ergo eos de terra Aegypti et eduxi in desertum;", "brenton": "And I brought them into the wilderness."}}, {"v": 11, "ref": "20:11", "o": "וָ/אֶתֵּ֤ן לָ/הֶם֙ אֶת חֻקּוֹתַ֔/י וְ/אֶת מִשְׁפָּטַ֖/י הוֹדַ֣עְתִּי אוֹתָ֑/ם אֲשֶׁ֨ר יַעֲשֶׂ֥ה אוֹתָ֛/ם הָ/אָדָ֖ם וָ/חַ֥י בָּ/הֶֽם", "en": {"kjv": "And I gave them my statutes, and shewed them my judgments, which if a man do, he shall even live in them.", "web": "I gave them my statutes, and showed them my ordinances, which if a man does, he shall live in them.", "bsb": "And I gave them My statutes and made known to them My ordinances—for the man who does these things will live by them.", "asv": "And I gave them my statutes, and showed them mine ordinances, which if a man do, he shall live in them.", "ylt": "And I give to them My statutes, And my judgments I caused them to know, Which the man who doth--liveth by them.", "dra": "And I gave them my statutes, and I shewed them my judgments, which if a man do, he shall live in them.", "bbe": "And I gave them my rules and made clear to them my orders, which, if a man keeps them, will be life to him.", "geneva": "And I gaue them my statutes, and declared my iudgements vnto them, which if a man doe, he shall liue in them.", "wycliffe": "and Y yaf to hem my comaundementis, and Y schewide to hem my doomes, which a man schal do, and lyue in tho.", "rotherham": "Then gave I unto them my statutes, And my regulations, caused I them to know,- By the which the man that doeth them shall live.", "darby": "And I gave them my statutes, and made known unto them mine ordinances, which if a man do, he shall live by them.", "twenty": "", "jps": "And I gave them My statutes, and taught them Mine ordinances, which if a man do, he shall live by them.", "acv": "And I gave them my statutes, and showed them my ordinances, which if a man does, he shall live in them.", "anderson": "", "haweis": "", "noyes": "And I gave them my statutes, and made known to them my laws, through which the man that keepeth them shall live.", "webster": "And I gave them my statutes, and showed them my judgments, which [if] a man doeth, he shall even live in them.", "vulgate": "et dedi eis praecepta mea et iudicia mea ostendi eis quae faciat homo et vivat in eis;", "brenton": "And I gave them my commandments, and made known to them mine ordinances, all which if a man shall do, he shall even live in them."}}, {"v": 12, "ref": "20:12", "o": "וְ/גַ֤ם אֶת שַׁבְּתוֹתַ/י֙ נָתַ֣תִּי לָ/הֶ֔ם לִ/הְי֣וֹת לְ/א֔וֹת בֵּינִ֖/י וּ/בֵֽינֵי/הֶ֑ם לָ/דַ֕עַת כִּ֛י אֲנִ֥י יְהוָ֖ה מְקַדְּשָֽׁ/ם", "en": {"kjv": "Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I am the Lord that sanctify them.", "web": "Moreover also I gave them my Sabbaths, to be a sign between me and them, that they might know that I am Yahweh who sanctifies them.", "bsb": "I also gave them My Sabbaths as a sign between us, so that they would know that I am the LORD who sanctifies them.", "asv": "Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I am Jehovah that sanctifieth them.", "ylt": "And also My sabbaths I have given to them, To be for a sign between Me and them, To know that I am Jehovah their sanctifier.", "dra": "Moreover I gave them also my sabbaths, to be a sign between me and them: and that they might know that I am the Lord that sanctify them.", "bbe": "And further, I gave them my Sabbaths, to be a sign between me and them, so that it might be clear that I, who make them holy, am the Lord.", "geneva": "Moreouer I gaue them also my Sabbaths to be a signe betweene me and them, that they might knowe that I am the Lord, that sanctifie them.", "wycliffe": "Ferthermore and Y yaf to hem my sabatis, that it schulde be a sygne bitwixe me and hem, and that thei schulden wite, that Y am the Lord halewynge hem.", "rotherham": "Moreover also my sabbaths, gave I unto them, to become a sign betwixt me and them,—that it might be known that, I, Yahweh, was hallowing them.", "darby": "And I also gave them my sabbaths, to be a sign between me and them, that they might know that I [am] Jehovah that hallow them.", "twenty": "", "jps": "Moreover also I gave them My sabbaths, to be a sign between Me and them, that they might know that I am HaShem that sanctify them.", "acv": "Moreover I also gave them my sabbaths, to be a sign between me and them, that they might know that I am Jehovah who sanctifies them.", "anderson": "", "haweis": "", "noyes": "Also I gave them my sabbaths, that they might be a sign between me and them, that they might know that I, Jehovah, sanctify them.", "webster": "Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I [am] the LORD that sanctify them.", "vulgate": "insuper et sabbata mea dedi eis ut esset signum inter me et eos et scirent quia ego Dominus sanctificans eos;", "brenton": "And I gave them my sabbaths, that they should be for a sign between me and them, that they should know that I am the Lord that sanctify them."}}, {"v": 13, "ref": "20:13", "o": "וַ/יַּמְרוּ בִ֨/י בֵֽית יִשְׂרָאֵ֜ל בַּ/מִּדְבָּ֗ר בְּ/חֻקּוֹתַ֨/י לֹא הָלָ֜כוּ וְ/אֶת מִשְׁפָּטַ֣/י מָאָ֗סוּ אֲשֶׁר֩ יַעֲשֶׂ֨ה אֹתָ֤/ם הָֽ/אָדָם֙ וָ/חַ֣י בָּ/הֶ֔ם וְ/אֶת שַׁבְּתֹתַ֖/י חִלְּל֣וּ מְאֹ֑ד וָ/אֹמַ֞ר לִ/שְׁפֹּ֨ךְ חֲמָתִ֧/י עֲלֵי/הֶ֛ם בַּ/מִּדְבָּ֖ר לְ/כַלּוֹתָֽ/ם", "en": {"kjv": "But the house of Israel rebelled against me in the wilderness: they walked not in my statutes, and they despised my judgments, which if a man do, he shall even live in them; and my sabbaths they greatly polluted: then I said, I would pour out my fury upon them in the wilderness, to consume them.", "web": "But the house of Israel rebelled against me in the wilderness: they didn’t walk in my statutes, and they rejected my ordinances, which if a man keep, he shall live in them; and my Sabbaths they greatly profaned. Then I said I would pour out my wrath on them in the wilderness, to consume them.", "bsb": "Yet the house of Israel rebelled against Me in the wilderness. They did not follow My statutes and they rejected My ordinances—though the man who does these things will live by them—and they utterly profaned My Sabbaths. Then I resolved to pour out My wrath upon them and put an end to them in the wilderness.", "asv": "But the house of Israel rebelled against me in the wilderness: they walked not in my statutes, and they rejected mine ordinances, which if a man keep, he shall live in them; and my sabbaths they greatly profaned. Then I said I would pour out my wrath upon them in the wilderness, to consume them.", "ylt": "And--rebel against me do the house of Israel in the wilderness, In My statutes they have not walked, And My judgments they have despised, Which the man who doth--liveth by them. And My sabbaths they have greatly polluted, And I say to pour out My fury on them in the wilderness, to consume them.", "dra": "But the house of Israel provoked me in the desert: they walked not in my statutes, and they cast away my judgments, which if a man do he shall live in them: and they grievously violated my sabbaths. I said therefore that I would pour out my indignation upon them in the desert, and would consume them.", "bbe": "But the children of Israel would not be controlled by me in the waste land: they were not guided by my rules, and they were turned away from my orders, which, if a man does them, will be life to him; and they had no respect for my Sabbaths: then I said that I would let loose my passion on them in the waste land, and put an end to them.", "geneva": "But the house of Israel rebelled against me in the wildernes: they walked not in my statutes, and they cast away my iudgements, which if a man doe, he shall liue in them, and my Sabbaths haue they greatly polluted: then I thought to powre out mine indignation vpon them in the wildernes to consume them,", "wycliffe": "And the hous of Israel terriden me to wraththe in desert; thei yeden not in my comaundementis, and thei castiden awei my domes, whiche a man that doith, schal lyue in tho; and thei defouliden greetli my sabatis. Therfor Y seide, that Y wolde schede out my strong veniaunce on hem in desert, and waste hem;", "rotherham": "But the house of Israel, rebelled against me, in the desert, In my statutes, walked they not, And my regulations, they rejected By the which the man, that doeth them, shall live, My sabbaths also, they profaned exceedingly. Therefore spake I of pouring out mine indignation upon them in the desert, to make an end of them.", "darby": "But the house of Israel rebelled against me in the wilderness: they walked not in my statutes, and they rejected mine ordinances, which if a man do, he shall live by them; and my sabbaths they greatly profaned: and I said I would pour out my fury upon them in the wilderness, to consume them.", "twenty": "", "jps": "But the house of Israel rebelled against Me in the wilderness; they walked not in My statutes, and they rejected Mine ordinances, which if a man do, he shall live by them, and My sabbaths they greatly profaned; then I said I would pour out My fury upon them in the wilderness, to consume them.", "acv": "But the house of Israel rebelled against me in the wilderness. They did not walk in my statutes, and they rejected my ordinances, which if a man keeps, he shall live in them. And they greatly profaned my sabbaths. Then I said I would pour out my wrath upon them in the wilderness, to consume them.", "anderson": "", "haweis": "", "noyes": "But the house of Israel rebelled against me in the desert; they walked not in my statutes, and they despised my laws, through which the man that keepeth them shall live, and my sabbaths they greatly polluted. Then I said that I would pour out my fury upon them in the desert, to consume them.", "webster": "But the house of Israel rebelled against me in the wilderness: they walked not in my statutes, and they despised my judgments, which [if] a man doeth, he shall even live in them; and my sabbaths they greatly profaned: then I said, I would pour out my fury upon them in the wilderness, to consume them.", "vulgate": "et inritaverunt me domus Israhel in deserto in praeceptis meis non ambulaverunt et iudicia mea proiecerunt quae faciens homo vivet in eis et sabbata mea violaverunt vehementer dixi ergo ut effunderem furorem meum super eos in deserto et consumerem eos;", "brenton": "And I said to the house of Israel in the wilderness, Walk ye in my commandments: but they walked not in them, and they rejected mine ordinances, which if a man shall do, he shall even live in them; and they grievously profaned my sabbaths: and I said that I would pour out my wrath upon them in the wilderness, to consume them."}}, {"v": 14, "ref": "20:14", "o": "וָ/אֶעֱשֶׂ֖ה לְמַ֣עַן שְׁמִ֑/י לְ/בִלְתִּ֤י הֵחֵל֙ לְ/עֵינֵ֣י הַ/גּוֹיִ֔ם אֲשֶׁ֥ר הוֹצֵאתִ֖י/ם לְ/עֵינֵי/הֶֽם", "en": {"kjv": "But I wrought for my name’s sake, that it should not be polluted before the heathen, in whose sight I brought them out.", "web": "But I worked for my name’s sake, that it should not be profaned in the sight of the nations, in whose sight I brought them out.", "bsb": "But I acted for the sake of My name, so that it would not be profaned in the eyes of the nations in whose sight I had brought them out.", "asv": "But I wrought for my name’s sake, that it should not be profaned in the sight of the nations, in whose sight I brought them out.", "ylt": "And I do it for My name's sake, Not to pollute it before the eyes of the nations, Before whose eyes I brought them forth.", "dra": "But I spared them for the sake of my name, lest it should be profaned before the nations, from which I brought them out, in their sight.", "bbe": "And I was acting for the honour of my name, so that it might not be made unclean in the eyes of the nations, before whose eyes I had taken them out.", "geneva": "But I had respect to my Name, that it shoulde not bee polluted before the heathen in whose sight I brought them out.", "wycliffe": "and Y dide for my name, lest it were defoulid bifor hethene men, fro whiche Y castide hem out in the siyt of tho.", "rotherham": "Howbeit I wrought with effect for the sake of mine own Name,—that it should not be profaned in the eyes of the nations, in whose eyes I had brought them forth.", "darby": "But I wrought for my name's sake, that it should not be profaned in the sight of the nations, in whose sight I had brought them out.", "twenty": "", "jps": "But I wrought for My name's sake, that it should not be profaned in the sight of the nations, in whose sight I brought them out.", "acv": "But I worked for my name's sake, that it should not be profaned in the sight of the nations, in whose sight I brought them out.", "anderson": "", "haweis": "", "noyes": "But I acted for my name’s sake, that it might not be polluted before the nations, in whose sight I brought them forth.", "webster": "But I wrought for my name's sake, that it should not be profaned before the heathen, in whose sight I brought them out.", "vulgate": "et feci propter nomen meum ne violaretur coram gentibus de quibus eieci eos in conspectu earum;", "brenton": "But I wrought so that my name should not be at all profaned before the Gentiles, before whose eyes I brought them out."}}, {"v": 15, "ref": "20:15", "o": "וְ/גַם אֲנִ֗י נָשָׂ֧אתִי יָדִ֛/י לָ/הֶ֖ם בַּ/מִּדְבָּ֑ר לְ/בִלְתִּי֩ הָבִ֨יא אוֹתָ֜/ם אֶל הָ/אָ֣רֶץ אֲשֶׁר נָתַ֗תִּי זָבַ֤ת חָלָב֙ וּ/דְבַ֔שׁ צְבִ֥י הִ֖יא לְ/כָל הָ/אֲרָצֽוֹת", "en": {"kjv": "Yet also I lifted up my hand unto them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the glory of all lands;", "web": "Moreover also I swore to them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the glory of all lands;", "bsb": "Moreover, with an uplifted hand I swore to them in the wilderness that I would not bring them into the land that I had given them—a land flowing with milk and honey, the glory of all lands—", "asv": "Moreover also I sware unto them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the glory of all lands;", "ylt": "And also, I, I have lifted up My hand to them in the wilderness, Not to bring them in to the land that I had given, Flowing with milk and honey, A beauty it is to all the lands,", "dra": "So I lifted up my hand over them in the desert, not to bring them into the land which I had given them flowing with milk and honey, the best of all lands.", "bbe": "And further, I gave my oath to them in the waste land, that I would not take them into the land which I had given them, a land flowing with milk and honey, the glory of all lands;", "geneva": "Yet neuerthelesse, I lift vp mine hande vnto them in the wildernes that I would not bring them into the lande, which I had giuen them, flowing with milke and hony, which was pleasant aboue all landes,", "wycliffe": "Therfor Y reiside myn hond on hem in the desert, that Y brouyte not hem in to the lond which Y yaf to hem, the lond flowynge with mylk and hony, the beste of alle londis.", "rotherham": "Yet even I lifted up my hand to them. in the desert,— That I would not bring them into the land which I had given to them flowing with milk and honey, The beauty, it was. of all lands:", "darby": "And I also lifted up my hand unto them in the wilderness, that I would not bring them into the land that I had given [them], flowing with milk and honey, which is the ornament of all lands;", "twenty": "", "jps": "Yet also I lifted up My hand unto them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the beauty of all lands;", "acv": "Moreover also I swore to them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the glory of all lands,", "anderson": "", "haweis": "", "noyes": "Yet I lifted up my hand to them in the desert, that I would not bring them into the land which I had given them, flowing with milk and honey, the beauty of all lands;", "webster": "Yet also I lifted up my hand to them in the wilderness, that I would not bring them into the land which I had given [them], flowing with milk and honey, which [is] the glory of all lands;", "vulgate": "ego igitur levavi manum meam super eos in deserto ne inducerem eos in terram quam dedi eis fluentem lacte et melle praecipuam terrarum omnium;", "brenton": "But I lifted up my hand against them in the wilderness once for all, that I would not bring them into the land which I gave them, a land flowing with milk and honey, it is sweeter than all lands:"}}, {"v": 16, "ref": "20:16", "o": "יַ֜עַן בְּ/מִשְׁפָּטַ֣/י מָאָ֗סוּ וְ/אֶת חֻקּוֹתַ/י֙ לֹא הָלְכ֣וּ בָ/הֶ֔ם וְ/אֶת שַׁבְּתוֹתַ֖/י חִלֵּ֑לוּ כִּ֛י אַחֲרֵ֥י גִלּוּלֵי/הֶ֖ם לִבָּ֥/ם הֹלֵֽךְ", "en": {"kjv": "Because they despised my judgments, and walked not in my statutes, but polluted my sabbaths: for their heart went after their idols.", "web": "because they rejected my ordinances, and didn’t walk in my statutes, and profaned my Sabbaths: for their heart went after their idols.", "bsb": "because they kept rejecting My ordinances, refusing to walk in My statutes, and profaning My Sabbaths; for their hearts continually went after their idols.", "asv": "because they rejected mine ordinances, and walked not in my statutes, and profaned my sabbaths: for their heart went after their idols.", "ylt": "Because against My judgments they did kick, And in My statutes they have not walked, And My sabbaths they have polluted, For after their idols their heart is going.", "dra": "Because they cast off my judgments, and walked not in my statutes, and violated my sabbaths: for their heart went after idols.", "bbe": "Because they were turned away from my orders, and were not guided by my rules, and had no respect for my Sabbaths: for their hearts went after their images.", "geneva": "Because they cast away my iudgments, and walked not in my statutes, but haue polluted my Sabbaths: for their heart went after their idoles.", "wycliffe": "For thei castiden awei my domes, and yeden not in my comaundementis, and thei defouliden my sabatis; for the herte of hem yede after idols.", "rotherham": "Because my regulations, they had rejected. And as for my statutes, they had not walked therein, My sabbaths also, had they profaned; For after their manufactured gods, their heart had been going.", "darby": "because they rejected mine ordinances and walked not in my statutes, and profaned my sabbaths: for their heart went after their idols.", "twenty": "", "jps": "because they rejected Mine ordinances, and walked not in My statutes, and profaned My sabbaths--for their heart went after their idols.", "acv": "because they rejected my ordinances, and did not walk in my statutes, and profaned my sabbaths, for their heart went after their idols.", "anderson": "", "haweis": "", "noyes": "because they despised my laws, and walked not in my statutes, but polluted my sabbaths; for their heart went after their idols.", "webster": "Because they despised my judgments, and walked not in my statutes, but profaned my sabbaths: for their heart went after their idols.", "vulgate": "quia iudicia mea proiecerunt et in praeceptis meis non ambulaverunt et sabbata mea violaverunt post idola enim cor eorum gradiebatur;", "brenton": "because they rejected mine ordinances, and walked not in my commandments, but profaned my sabbaths, and went after the imaginations of their hearts."}}, {"v": 17, "ref": "20:17", "o": "וַ/תָּ֧חָס עֵינִ֛/י עֲלֵי/הֶ֖ם מִֽ/שַּׁחֲתָ֑/ם וְ/לֹֽא עָשִׂ֧יתִי אוֹתָ֛/ם כָּלָ֖ה בַּ/מִּדְבָּֽר", "en": {"kjv": "Nevertheless mine eye spared them from destroying them, neither did I make an end of them in the wilderness.", "web": "Nevertheless my eye spared them, and I didn’t destroy them, neither did I make a full end of them in the wilderness.", "bsb": "Yet I looked on them with pity and did not destroy them or bring them to an end in the wilderness.", "asv": "Nevertheless mine eye spared them, and I destroyed them not, neither did I make a full end of them in the wilderness.", "ylt": "And Mine eye hath pity on them--against destroying them, And I have not made of them an end in the wilderness.", "dra": "Yet my eye spared them, so that I destroyed them not: neither did I consume them in the desert.", "bbe": "But still my eye had pity on them and I kept them from destruction and did not put an end to them completely in the waste land.", "geneva": "Neuerthelesse, mine eye spared them, that I would not destroye them, neither would I consume them in the wildernes.", "wycliffe": "And myn iye sparide on hem, that Y killide not hem, nether Y wastide hem in the desert.", "rotherham": "Nevertheless mine eye threw a shield over them that they should not be destroyed; So I made not of them a full end in the desert.", "darby": "But mine eye spared them so as not to destroy them, neither did I make a full end of them in the wilderness.", "twenty": "", "jps": "Nevertheless Mine eye spared them from destroying them, neither did I make a full end of them in the wilderness.", "acv": "Nevertheless my eye spared them, and I did not destroy them, nor did I make a full end of them in the wilderness.", "anderson": "", "haweis": "", "noyes": "Nevertheless mine eye spared them, so that I did not destroy them; neither did I make an end of them in the desert.", "webster": "Nevertheless my eye spared them from destroying them, neither did I make an end of them in the wilderness.", "vulgate": "et pepercit oculus meus super eos ut non interficerem eos nec consumpsi eos in deserto;", "brenton": "Yet mine eyes spared them, so as not to destroy them utterly, and I did not make an end of them in the wilderness."}}, {"v": 18, "ref": "20:18", "o": "וָ/אֹמַ֤ר אֶל בְּנֵי/הֶם֙ בַּ/מִּדְבָּ֔ר בְּ/חוּקֵּ֤י אֲבֽוֹתֵי/כֶם֙ אַל תֵּלֵ֔כוּ וְ/אֶת מִשְׁפְּטֵי/הֶ֖ם אַל תִּשְׁמֹ֑רוּ וּ/בְ/גִלּוּלֵי/הֶ֖ם אַל תִּטַּמָּֽאוּ", "en": {"kjv": "But I said unto their children in the wilderness, Walk ye not in the statutes of your fathers, neither observe their judgments, nor defile yourselves with their idols:", "web": "I said to their children in the wilderness, Don’t walk in the statutes of your fathers, neither observe their ordinances, nor defile yourselves with their idols.", "bsb": "In the wilderness I said to their children: ‘Do not walk in the statutes of your fathers or keep their ordinances or defile yourselves with their idols.", "asv": "And I said unto their children in the wilderness, Walk ye not in the statutes of your fathers, neither observe their ordinances, nor defile yourselves with their idols.", "ylt": "And I say to their sons in the wilderness: In the statutes of your fathers ye walk not, And their judgments ye do not observe, And with their idols ye are not defiled.", "dra": "And I said to their children in the wilderness: Walk not in the statutes of your fathers, and observe not their judgments, nor be ye defiled with their idols:", "bbe": "And I said to their children in the waste land, Do not be guided by the rules of your fathers or keep their orders or make yourselves unclean with their images:", "geneva": "But I said vnto their children in the wildernes, Walke ye not in the ordinances of your fathers, neither obserue their maners, nor defile your selues with their idoles.", "wycliffe": "Forsothe Y seide to the sones of hem in wildirnesse, Nyle ye go in the comaundementis of youre fadris, nether kepe ye the domes of hem, nethir be ye defoulid in the idols of hem.", "rotherham": "But I said unto their children in the desert, In the statutes of your fathers, let it not be that ye walk, And their regulations, let it not be that ye observe,— And with their manufactured gods, let it not be that ye defile yourselves.", "darby": "And I said unto their children in the wilderness, Walk not in the statutes of your fathers, neither keep their ordinances, nor defile yourselves with their idols.", "twenty": "", "jps": "And I said unto their children in the wilderness: Walk ye not in the statutes of your fathers, neither observe their ordinances, nor defile yourselves with their idols;", "acv": "And I said to their sons in the wilderness, Walk ye not in the statutes of your fathers. Neither observe their ordinances, nor defile yourselves with their idols.", "anderson": "", "haweis": "", "noyes": "And I said to their sons in the desert, Walk ye not in the statutes of your fathers, neither observe their ordinances, nor defile yourselves with their idols!", "webster": "But I said to their children in the wilderness, Walk ye not in the statutes of your fathers, neither observe their judgments, nor defile yourselves with their idols:", "vulgate": "dixi autem ad filios eorum in solitudine in praeceptis patrum vestrorum nolite incedere nec iudicia eorum custodiatis nec in idolis eorum polluamini;", "brenton": "And I said to their children in the wilderness, Walk not ye in the customs of your fathers, and keep not their ordinances, and have no fellowship with their practices, nor defile yourselves with them."}}, {"v": 19, "ref": "20:19", "o": "אֲנִי֙ יְהוָ֣ה אֱלֹהֵי/כֶ֔ם בְּ/חֻקּוֹתַ֖/י לֵ֑כוּ וְ/אֶת מִשְׁפָּטַ֥/י שִׁמְר֖וּ וַ/עֲשׂ֥וּ אוֹתָֽ/ם", "en": {"kjv": "I am the Lord your God; walk in my statutes, and keep my judgments, and do them;", "web": "I am Yahweh your God: walk in my statutes, and keep my ordinances, and do them;", "bsb": "I am the LORD your God; walk in My statutes, keep My ordinances, and practice them.", "asv": "I am Jehovah your God: walk in my statutes, and keep mine ordinances, and do them;", "ylt": "I am Jehovah your God, in My statutes walk, And My judgments observe, and do them,", "dra": "I am the Lord your God: walk ye in my statutes, and observe my judgments, and do them.", "bbe": "I am the Lord your God; be guided by my rules and keep my orders and do them:", "geneva": "I am the Lord your God: walke in my statutes, and keepe my iudgements and doe them,", "wycliffe": "Y am youre Lord God, go ye in my comaundementis, and kepe ye my domes, and do ye tho.", "rotherham": "I, Yahweh, am your God, In my statutes, walk ye,— And my regulations, observe ye and do them;", "darby": "I [am] Jehovah yourGod: walk in my statutes, and keep mine ordinances, and do them;", "twenty": "", "jps": "I am HaShem your G-d; walk in My statutes, and keep Mine ordinances, and do them;", "acv": "I am Jehovah your God. Walk in my statutes, and keep my ordinances, and do them,", "anderson": "", "haweis": "", "noyes": "I am Jehovah, your God; walk in my statutes, and keep my ordinances, and do them.", "webster": "I [am] the LORD your God; walk in my statutes, and keep my judgments, and do them;", "vulgate": "ego Dominus Deus vester in praeceptis meis ambulate et iudicia mea custodite et facite ea;", "brenton": "I am the Lord your God; walk in my commandments, and keep mine ordinances, and do them;"}}, {"v": 20, "ref": "20:20", "o": "וְ/אֶת שַׁבְּתוֹתַ֖/י קַדֵּ֑שׁוּ וְ/הָי֤וּ לְ/אוֹת֙ בֵּינִ֣/י וּ/בֵֽינֵי/כֶ֔ם לָ/דַ֕עַת כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "And hallow my sabbaths; and they shall be a sign between me and you, that ye may know that I am the Lord your God.", "web": "and make my Sabbaths holy; and they shall be a sign between me and you, that you may know that I am Yahweh your God.", "bsb": "Keep My Sabbaths holy, that they may be a sign between us, so that you may know that I am the LORD your God.’", "asv": "and hallow my sabbaths; and they shall be a sign between me and you, that ye may know that I am Jehovah your God.", "ylt": "And My sabbaths sanctify, And they have been for a sign between Me and you, To know that I, Jehovah, am your God.", "dra": "And sanctify my sabbaths, that they may be a sign between me and you: and that you may know that I am the Lord your God.", "bbe": "And keep my Sabbaths holy; and they will be a sign between me and you so that it may be clear to you that I am the Lord your God.", "geneva": "And sanctifie my Sabbaths, and they shall bee a signe betweene mee and you, that ye may knowe that I am the Lord your God.", "wycliffe": "And halowe ye my sabatis, that it be a signe bitwixe me and you, and that it be knowun, that Y am youre Lord God.", "rotherham": "My sabbaths also, hallow ye,— And they shall become a sign betwixt me and you, That it may be known that I Yahweh am your God.", "darby": "and hallow my sabbaths; and they shall be a sign between me and you, that ye may know that I [am] Jehovah yourGod.", "twenty": "", "jps": "and hallow My sabbaths, and they shall be a sign between Me and you, that ye may know that I am HaShem your G-d.", "acv": "and hallow my sabbaths, and they shall be a sign between me and you, that ye may know that I am Jehovah your God.", "anderson": "", "haweis": "", "noyes": "And hallow my sabbaths, that they may be a sign between me and you, that ye may know that I am Jehovah, your God.", "webster": "And hallow my sabbaths; and they shall be a sign between me and you, that ye may know that I [am] the LORD your God.", "vulgate": "et sabbata mea sanctificate ut sit signum inter me et vos et sciatur quia ego Dominus Deus vester;", "brenton": "and hallow my sabbaths, and let them be a sign between me and you, that ye may know that I am the Lord your God."}}, {"v": 21, "ref": "20:21", "o": "וַ/יַּמְרוּ בִ֣/י הַ/בָּנִ֗ים בְּ/חֻקּוֹתַ֣/י לֹֽא הָ֠לָכוּ וְ/אֶת מִשְׁפָּטַ֨/י לֹא שָׁמְר֜וּ לַ/עֲשׂ֣וֹת אוֹתָ֗/ם אֲשֶׁר֩ יַעֲשֶׂ֨ה אוֹתָ֤/ם הָֽ/אָדָם֙ וָ/חַ֣י בָּ/הֶ֔ם אֶת שַׁבְּתוֹתַ֖/י חִלֵּ֑לוּ וָ/אֹמַ֞ר לִ/שְׁפֹּ֧ךְ חֲמָתִ֣/י עֲלֵי/הֶ֗ם לְ/כַלּ֥וֹת אַפִּ֛/י בָּ֖/ם בַּ/מִּדְבָּֽר", "en": {"kjv": "Notwithstanding the children rebelled against me: they walked not in my statutes, neither kept my judgments to do them, which if a man do, he shall even live in them; they polluted my sabbaths: then I said, I would pour out my fury upon them, to accomplish my anger against them in the wilderness.", "web": "But the children rebelled against me; they didn’t walk in my statutes, neither kept my ordinances to do them, which if a man do, he shall live in them; they profaned my Sabbaths. Then I said I would pour out my wrath on them, to accomplish my anger against them in the wilderness.", "bsb": "But the children rebelled against Me. They did not walk in My statutes or carefully observe My ordinances—though the man who does these things will live by them—and they profaned My Sabbaths. So I resolved to pour out My wrath upon them and vent My anger against them in the wilderness.", "asv": "But the children rebelled against me; they walked not in my statutes, neither kept mine ordinances to do them, which if a man do, he shall live in them; they profaned my sabbaths. Then I said I would pour out my wrath upon them, to accomplish my anger against them in the wilderness.", "ylt": "And--the sons rebel against Me, In My statutes they have not walked, And My judgments they have not observed--to do them, Which the man who doth--liveth by them. My sabbaths they have polluted, And I say to pour out My fury upon them, To complete Mine anger against them in the wilderness.", "dra": "But their children provoked me, they walked not in my commandments, nor observed my judgments to do them: which if a man do, he shall live in them: and they violated my sabbaths: and I threatened to pour out my indignation upon them, and to accomplish my wrath in them in the desert.", "bbe": "But the children would not be controlled by me; they were not guided by my rules, and they did not keep and do my orders, which, if a man does them, will be life to him; and they had no respect for my Sabbaths: then I said I would let loose my passion on them to give full effect to my wrath against them in the waste land.", "geneva": "Notwithstanding the children rebelled against mee: they walked not in my statutes, nor kept my iudgements to doe them, which if a man doe, hee shall liue in them, but they polluted my Sabbaths: then I thought to powre out mine indignation vpon them, and to accomplish my wrath against them in the wildernes.", "wycliffe": "And the sones terriden me to wraththe, and yeden not in my comaundementis, and kepten not my domes, that thei diden tho, whiche whanne a man hath do, he schal lyue in tho, and thei defouliden my sabatis. And Y manaasside to hem, that Y wolde schede out my stronge veniaunce on hem, and fille my wraththe in hem in the desert.", "rotherham": "Notwithstanding the children rebelled against me, In my statutes, walked they not, And my regulations, observed they not to do them Wherein the man who shall do them shall live, My sabbaths, they profaned. Therefore spake I of pouring out mine indignation upon them to bring mine anger to an end against them. in the desert.", "darby": "And the children rebelled against me: they walked not in my statutes, neither kept mine ordinances to do them, which if a man do, he shall live by them; they profaned my sabbaths: and I said I would pour out my fury upon them, to accomplish mine anger against them in the wilderness.", "twenty": "", "jps": "But the children rebelled against Me; they walked not in My statutes, neither kept Mine ordinances to do them, which if a man do, he shall live by them; they profaned My sabbaths; then I said I would pour out My fury upon them, to spend My anger upon them in the wilderness.", "acv": "But the sons rebelled against me. They did not walk in my statutes, nor kept my ordinances to do them, which if a man does, he shall live in them. They profaned my sabbaths. Then I said I would pour out my wrath upon them, to accomplish my anger against them in the wilderness.", "anderson": "", "haweis": "", "noyes": "But the sons rebelled against me; they walked not in my statutes, neither kept they my ordinances to do them, through which the man that doeth them shall live, and they polluted my sabbaths. Then I said that I would pour out my fury upon them, and accomplish mine anger upon them in the desert.", "webster": "Notwithstanding the children rebelled against me: they walked not in my statutes, neither kept my judgments to do them, which [if] a man doeth, he shall even live in them: they profaned my sabbaths: then I said, I would pour out my fury upon them, to accomplish my anger against them in the wilderness.", "vulgate": "et exacerbaverunt me filii in praeceptis meis non ambulaverunt et iudicia mea non custodierunt ut facerent ea quae cum fecerit homo vivet in eis et sabbata mea violaverunt et comminatus sum ut effunderem furorem meum super eos et implerem iram meam in eis in deserto;", "brenton": "But they provoked me, and their children walked not in my commandments, and they took no heed to mine ordinances to do them, which if a man shall do, he shall even live in them, and they profaned my sabbaths: then I said that I would pour out my wrath upon them in the wilderness, to accomplish mine anger upon them."}}, {"v": 22, "ref": "20:22", "o": "וַ/הֲשִׁבֹ֨תִי֙ אֶת יָדִ֔/י וָ/אַ֖עַשׂ לְמַ֣עַן שְׁמִ֑/י לְ/בִלְתִּ֤י הֵחֵל֙ לְ/עֵינֵ֣י הַ/גּוֹיִ֔ם אֲשֶׁר הוֹצֵ֥אתִי אוֹתָ֖/ם לְ/עֵינֵי/הֶֽם", "en": {"kjv": "Nevertheless I withdrew mine hand, and wrought for my name’s sake, that it should not be polluted in the sight of the heathen, in whose sight I brought them forth.", "web": "Nevertheless I withdrew my hand, and worked for my name’s sake, that it should not be profaned in the sight of the nations, in whose sight I brought them out.", "bsb": "But I withheld My hand and acted for the sake of My name, so that it would not be profaned in the eyes of the nations in whose sight I had brought them out.", "asv": "Nevertheless I withdrew my hand, and wrought for my name’s sake, that it should not be profaned in the sight of the nations, in whose sight I brought them forth.", "ylt": "And I have turned back My hand, And I do it for My name's sake, Not to pollute it before the eyes of the nations, Before whose eyes I brought them out.", "dra": "But I turned away my hand, and wrought for my name's sake, that it might not be violated before the nations, out of which I brought them forth in their sight.", "bbe": "And I was acting for the honour of my name, so that it might not be made unclean in the eyes of the nations, before whose eyes I had taken them out.", "geneva": "Neuerthelesse I withdrew mine hand and had respect to my Name that it should not be polluted before the heathen, in whose sight I brought them foorth.", "wycliffe": "But Y turnede awei myn hond, and Y dide this for my name, that it were not defoulid bifore hethene men, fro whiche Y castide hem out bifore the iyen of tho.", "rotherham": "Howbeit I withdrew my hand, and wrought with effect for the sake of mine own Name, —that it should not be profaned before the eyes of the nations, before whose eyes I had brought them forth:", "darby": "But I withdrew my hand, and wrought for my name's sake, that it should not be profaned in the sight of the nations, in whose sight I had brought them out.", "twenty": "", "jps": "Nevertheless I withdrew My hand, and wrought for My name's sake, that it should not be profaned in the sight of the nations, in whose sight I brought them forth.", "acv": "Nevertheless I withdrew my hand, and worked for my name's sake, that it should not be profaned in the sight of the nations, in whose sight I brought them forth.", "anderson": "", "haweis": "", "noyes": "Nevertheless I held back my hand, and acted for my name’s sake, that it should not be polluted before the nations, in whose sight I brought them forth.", "webster": "Nevertheless I withdrew my hand, and wrought for my name's sake, that it should not be profaned in the sight of the heathen, in whose sight I brought them forth.", "vulgate": "averti autem manum meam et feci propter nomen meum ut non violaretur coram gentibus de quibus eieci eos in oculis earum;", "brenton": "But I wrought so that my name might not be at all profaned before the Gentiles; and I brought them out in their sight."}}, {"v": 23, "ref": "20:23", "o": "גַּם אֲנִ֗י נָשָׂ֧אתִי אֶת יָדִ֛/י לָ/הֶ֖ם בַּ/מִּדְבָּ֑ר לְ/הָפִ֤יץ אֹתָ/ם֙ בַּ/גּוֹיִ֔ם וּ/לְ/זָר֥וֹת אוֹתָ֖/ם בָּ/אֲרָצֽוֹת", "en": {"kjv": "I lifted up mine hand unto them also in the wilderness, that I would scatter them among the heathen, and disperse them through the countries;", "web": "Moreover I swore to them in the wilderness, that I would scatter them among the nations, and disperse them through the countries;", "bsb": "However, with an uplifted hand I swore to them in the wilderness that I would scatter them among the nations and disperse them throughout the lands.", "asv": "Moreover I sware unto them in the wilderness, that I would scatter them among the nations, and disperse them through the countries;", "ylt": "I also, I have lifted up My hand to them in the wilderness, To scatter them among nations, And to spread them through lands.", "dra": "Again I lifted up my hand upon them in the wilderness, to disperse them among the nations, and scatter them through the countries:", "bbe": "Further, I gave my oath to them in the waste land that I would send them wandering among the nations, driving them out among the countries;", "geneva": "Yet I lift vp mine hande vnto them in the wildernes, that I would scatter them among the heathen, and disperse them through the countreys,", "wycliffe": "Eft Y reiside myn hond ayens hem in wildirnesse, that Y schulde scatere hem in to naciouns, and wyndewe hem in to londis;", "rotherham": "Even, I, lifted up my hand to them in the desert,— That I would disperse them throughout the nations, And scatter them throughout the lands;", "darby": "I lifted up my hand also unto them in the wilderness, that I would scatter them among the nations, and disperse them through the countries;", "twenty": "", "jps": "I lifted up My hand unto them also in the wilderness, that I would scatter them among the nations, and disperse them through the countries;", "acv": "Moreover I swore to them in the wilderness, that I would scatter them among the nations, and disperse them through the countries,", "anderson": "", "haweis": "", "noyes": "I also lifted up my hand against them in the desert, that I would scatter them among the nations, and disperse them through the countries,", "webster": "I lifted up my hand to them also in the wilderness, that I would scatter them among the heathen, and disperse them through the countries;", "vulgate": "iterum levavi manum meam in eos in solitudine ut dispergerem illos in nationes et ventilarem in terras;", "brenton": "I lifted up my hand against them in the wilderness, that I would scatter them among the Gentiles, and disperse them in the countries;"}}, {"v": 24, "ref": "20:24", "o": "יַ֜עַן מִשְׁפָּטַ֤/י לֹֽא עָשׂוּ֙ וְ/חֻקּוֹתַ֣/י מָאָ֔סוּ וְ/אֶת שַׁבְּתוֹתַ֖/י חִלֵּ֑לוּ וְ/אַחֲרֵי֙ גִּלּוּלֵ֣י אֲבוֹתָ֔/ם הָי֖וּ עֵינֵי/הֶֽם", "en": {"kjv": "Because they had not executed my judgments, but had despised my statutes, and had polluted my sabbaths, and their eyes were after their fathers’ idols.", "web": "because they had not executed my ordinances, but had rejected my statutes, and had profaned my Sabbaths, and their eyes were after their fathers’ idols.", "bsb": "For they did not practice My ordinances, but they rejected My statutes and profaned My Sabbaths, fixing their eyes on the idols of their fathers.", "asv": "because they had not executed mine ordinances, but had rejected my statutes, and had profaned my sabbaths, and their eyes were after their fathers’ idols.", "ylt": "Because My judgments they have not done, And My statutes they have despised, And My sabbaths they have polluted, And after idols of their fathers have their eyes been.", "dra": "Because they had not done my judgments, and had cast off my statutes, and had violated my sabbaths, and their eyes had been after the idols of their fathers.", "bbe": "Because they had not done my orders, but had been turned away from my rules, and had not given respect to my Sabbaths, and their eyes were turned to the images of their fathers.", "geneva": "Because they had not executed my iudgements, but had cast away my statutes and had polluted my Sabbaths, and their eyes were after their fathers idoles.", "wycliffe": "for that that thei hadden not do my domes, and hadden repreuyd my comaundementis, and hadden defoulid my sabatis, and her iyen hadden be after the idols of her fadris.", "rotherham": "Because my regulations, had they not done And my statutes, they had rejected, My sabbaths also, they had profaned,- And after the manufactured gods of their fathers, were their eyes turned.", "darby": "because they performed not mine ordinances, and rejected my statutes, and profaned my sabbaths, and their eyes were after their fathers' idols.", "twenty": "", "jps": "because they had not executed Mine ordinances, but had rejected My statutes, and had profaned My sabbaths, and their eyes were after their fathers' idols.", "acv": "because they had not executed my ordinances, but had rejected my statutes, and had profaned my sabbaths, and their eyes were after their fathers' idols.", "anderson": "", "haweis": "", "noyes": "because they did not observe mine ordinances, but despised my statutes, and polluted my sabbaths, and their eyes were after the idols of their fathers.", "webster": "Because they had not executed my judgments, but had despised my statutes, and had profaned my sabbaths, and their eyes were after their fathers' idols.", "vulgate": "eo quod iudicia mea non fecissent et praecepta mea reprobassent et sabbata mea violassent et post idola patrum suorum fuissent oculi eorum;", "brenton": "because they kept not mine ordinances, and rejected my commandments, and profaned my sabbaths, and their eyes went after the imaginations of their fathers."}}, {"v": 25, "ref": "20:25", "o": "וְ/גַם אֲנִי֙ נָתַ֣תִּי לָ/הֶ֔ם חֻקִּ֖ים לֹ֣א טוֹבִ֑ים וּ/מִ֨שְׁפָּטִ֔ים לֹ֥א יִֽחְי֖וּ בָּ/הֶֽם", "en": {"kjv": "Wherefore I gave them also statutes that were not good, and judgments whereby they should not live;", "web": "Moreover also I gave them statutes that were not good, and ordinances in which they should not live;", "bsb": "I also gave them over to statutes that were not good and ordinances by which they could not live.", "asv": "Moreover also I gave them statutes that were not good, and ordinances wherein they should not live;", "ylt": "And I also, I have given to them statutes not good, And judgments by which they do not live.", "dra": "Therefore I also gave them statutes that were not good, and judgments, in which they shall not live.", "bbe": "And further, I gave them rules which were not good and orders in which there was no life for them;", "geneva": "Wherefore I gaue them also statutes that were not good, and iudgements, wherein they should not liue.", "wycliffe": "Therfor and Y yaf to hem comaundementis not good, and domes in whiche thei schulen not lyue.", "rotherham": "I myself, indeed, suffered them to walk in statutes which were not good,— And regulations in which they could not live.", "darby": "And I also gave them statutes that were not good, and ordinances whereby they should not live;", "twenty": "", "jps": "Wherefore I gave them also statutes that were not good, and ordinances whereby they should not live;", "acv": "Moreover I also gave them statutes that were not good, and ordinances in which they will not live.", "anderson": "", "haweis": "", "noyes": "Moreover I gave them statutes that were not good, and ordinances by which they should not live.", "webster": "Wherefore I gave them also statutes [that were] not good, and judgments by which they should not live;", "vulgate": "ergo et ego dedi eis praecepta non bona et iudicia in quibus non vivent;", "brenton": "So I gave them commandments that were not good, and ordinances in which they should not live."}}, {"v": 26, "ref": "20:26", "o": "וָ/אֲטַמֵּ֤א אוֹתָ/ם֙ בְּ/מַתְּנוֹתָ֔/ם בְּ/הַעֲבִ֖יר כָּל פֶּ֣טֶר רָ֑חַם לְמַ֣עַן אֲשִׁמֵּ֔/ם לְמַ֨עַן֙ אֲשֶׁ֣ר יֵֽדְע֔וּ אֲשֶׁ֖ר אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I polluted them in their own gifts, in that they caused to pass through the fire all that openeth the womb, that I might make them desolate, to the end that they might know that I am the Lord.", "web": "and I polluted them in their own gifts, in that they caused all that opens the womb to pass through the fire, that I might make them desolate, to the end that they might know that I am Yahweh.", "bsb": "And I pronounced them unclean through their gifts—the sacrifice of every firstborn in the fire—so that I might devastate them, in order that they would know that I am the LORD.", "asv": "and I polluted them in their own gifts, in that they caused to pass through the fire all that openeth the womb, that I might make them desolate, to the end that they might know that I am Jehovah.", "ylt": "And I defile them by their own gifts, By causing to pass away every opener of a womb, So that I make them desolate, So that they know that I am Jehovah.", "dra": "And I polluted them in their own gifts, when they offered all that opened the womb, for their offences: and they shall know that I am the Lord.", "bbe": "I made them unclean in the offerings they gave, causing them to make every first child go through the fire, so that I might put an end to them.", "geneva": "And I polluted them in their owne giftes in that they caused to passe by the fire all that first openeth ye wombe, that I might destroy them, to the ende, that they might know that I am ye Lord.", "wycliffe": "And Y defoulide hem in her yiftis, whanne thei offriden to me for her trespassis al thing that openeth the wombe; and thei schulen wite, that Y am the Lord.", "rotherham": "Yea I let them defile themselves with their gifts, when they caused every firstborn to pass through the fire,-.that I might make them desolate. To the end they might know that, I, am Yahweh.", "darby": "and I defiled them by their own gifts, in that they devoted all that opened the womb, that I might make them desolate, to the end that they might know that I [am] Jehovah.", "twenty": "", "jps": "and I polluted them in their own gifts, in that they set apart all that openeth the womb, that I might destroy them, to the end that they might know that I am HaShem.", "acv": "And I polluted them in their own gifts, in that they caused to pass through the fire all that opens the womb, that I might make them desolate, to the end that they might know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I polluted them in their offerings, in that they caused every first-born child to pass through the fire, that I might destroy them, to the end that they might know that I am Jehovah.", "webster": "And I polluted them in their own gifts, in that they caused to pass through [the fire] all the first-born, that I might make them desolate, to the end that they might know that I [am] the LORD.", "vulgate": "et pollui eos in muneribus suis cum offerrent omne quod aperit vulvam propter delicta sua et scient quia ego Dominus;", "brenton": "And I will defile them by their own decrees, when I pass through upon every one that opens the womb, that I may destroy them."}}, {"v": 27, "ref": "20:27", "o": "לָ/כֵ֞ן דַּבֵּ֨ר אֶל בֵּ֤ית יִשְׂרָאֵל֙ בֶּן אָדָ֔ם וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה ע֗וֹד זֹ֚את גִּדְּפ֤וּ אוֹתִ/י֙ אֲב֣וֹתֵי/כֶ֔ם בְּ/מַעֲלָ֥/ם בִּ֖/י מָֽעַל", "en": {"kjv": "Therefore, son of man, speak unto the house of Israel, and say unto them, Thus saith the Lord God; Yet in this your fathers have blasphemed me, in that they have committed a trespass against me.", "web": "Therefore, son of man, speak to the house of Israel, and tell them, Thus says the Lord Yahweh: In this moreover have your fathers blasphemed me, in that they have committed a trespass against me.", "bsb": "Therefore, son of man, speak to the house of Israel, and tell them that this is what the Lord GOD says: In this way also your fathers blasphemed Me by their unfaithfulness against Me.", "asv": "Therefore, son of man, speak unto the house of Israel, and say unto them, Thus saith the Lord Jehovah: In this moreover have your fathers blasphemed me, in that they have committed a trespass against me.", "ylt": "Therefore, speak unto the house of Israel, son of man, and thou hast said unto them, Thus said the Lord Jehovah: Still in this have your fathers reviled Me, In their committing against Me a trespass.", "dra": "Wherefore speak to the house of Israel, O son of man, and say to them: Thus saith the Lord God: Moreover in this also your fathers blaspheme me, when they had despised and contemned me;", "bbe": "For this cause, son of man, say to the children of Israel, This is what the Lord has said: In this your fathers have further put shame on my name by doing wrong against me.", "geneva": "Therefore, sonne of man, speake vnto the house of Israel, and say vnto them, Thus saith the Lord God, Yet in this your fathers haue blasphemed me, though they had before grieuously transgressed against me.", "wycliffe": "Wherfor speke thou, sone of man, to the hous of Israel, and thou schalt seie to hem, The Lord God seith these thingis, Yit and in this youre fadris blasfemyden me, whanne thei dispisynge hadden forsake me,", "rotherham": "Therefore speak thou unto the house of Israel Son of man, and say unto them, Thus saith My Lord Yahweh,— Yet further in this, did your fathers insult me, by the treachery wherewith they dealt treacherously against me;", "darby": "Therefore, son of man, speak unto the house of Israel, and say unto them, Thus saith the Lord Jehovah: In this moreover have your fathers blasphemed me, in that they have wrought unfaithfulness against me.", "twenty": "", "jps": "Therefore, son of man, speak unto the house of Israel, and say unto them: Thus saith the L-rd GOD: In this moreover have your fathers blasphemed Me, in that they dealt treacherously with Me.", "acv": "Therefore, son of man, speak to the house of Israel, and say to them, Thus says the lord Jehovah: In this moreover your fathers have blasphemed me, in that they have committed a trespass against me.", "anderson": "", "haweis": "", "noyes": "Therefore speak to the house of Israel, O son of man, and say to them, Thus saith the Lord Jehovah: Yet in this your fathers dishonored me, and trespassed against me.", "webster": "Therefore, son of man, speak to the house of Israel, and say to them, Thus saith the Lord GOD; Yet in this your fathers have blasphemed me, in that they have committed a trespass against me.", "vulgate": "quam ob rem loquere ad domum Israhel fili hominis et dices ad eos haec dicit Dominus Deus adhuc et in hoc blasphemaverunt me patres vestri cum sprevissent me contemnentes;", "brenton": "Therefore, son of man, speak to the house of Israel, and thou shalt say to them, Thus saith the Lord: Hitherto have your fathers provoked me in their trespasses in which they transgressed against me."}}, {"v": 28, "ref": "20:28", "o": "וָ/אֲבִיאֵ/ם֙ אֶל הָ/אָ֔רֶץ אֲשֶׁ֤ר נָשָׂ֨אתִי֙ אֶת יָדִ֔/י לָ/תֵ֥ת אוֹתָ֖/הּ לָ/הֶ֑ם וַ/יִּרְאוּ֩ כָל גִּבְעָ֨ה רָמָ֜ה וְ/כָל עֵ֣ץ עָבֹ֗ת וַ/יִּזְבְּחוּ שָׁ֤ם אֶת זִבְחֵי/הֶם֙ וַ/יִּתְּנוּ שָׁם֙ כַּ֣עַס קָרְבָּנָ֔/ם וַ/יָּשִׂ֣ימוּ שָׁ֗ם רֵ֚יחַ נִיח֣וֹחֵי/הֶ֔ם וַ/יַּסִּ֥יכוּ שָׁ֖ם אֶת נִסְכֵּי/הֶֽם", "en": {"kjv": "For when I had brought them into the land, for the which I lifted up mine hand to give it to them, then they saw every high hill, and all the thick trees, and they offered there their sacrifices, and there they presented the provocation of their offering: there also they made their sweet savour, and poured out there their drink offerings.", "web": "For when I had brought them into the land, which I swore to give to them, then they saw every high hill, and every thick tree, and they offered there their sacrifices, and there they presented the provocation of their offering; there also they made their pleasant aroma, and they poured out there their drink offerings.", "bsb": "When I brought them into the land that I swore to give them and they saw any high hill or leafy tree, there they offered their sacrifices, presented offerings that provoked Me, sent up their fragrant incense, and poured out their drink offerings.", "asv": "For when I had brought them into the land, which I sware to give unto them, then they saw every high hill, and every thick tree, and they offered there their sacrifices, and there they presented the provocation of their offering; there also they made their sweet savor, and they poured out there their drink-offerings.", "ylt": "And I bring them in unto the land, That I did lift up My hand to give to them, And they see every high hill, and every thick tree, And they sacrifice there their sacrifices, And give there the provocation of their offering, And make there their sweet fragrance, And they pour out there their libations.", "dra": "And I had brought them into the land, for which I lifted up my hand to give it them: they saw every high hill, and every shady tree, and there they sacrificed their victims: and there they presented the provocation of their offerings, and there they set their sweet odours, and poured forth their libations.", "bbe": "For when I had taken them into the land which I made an oath to give to them, then they saw every high hill and every branching tree and made their offerings there, moving me to wrath by their offerings; and there the sweet smell of their offerings went up and their drink offerings were drained out.", "geneva": "For when I had brought them into the land, for the which I lifted vp mine hand to giue it to them, then they saw euery hie hill, and all the thicke trees, and they offred there their sacrifices, and there they presented their offering of prouocation: there also they made their sweete sauour, and powred out there their drinke offerings.", "wycliffe": "and Y hadde brouyte hem in to the lond on which Y reiside myn hond, that Y schulde yiue to hem, thei siyen ech hiy litil hil, and ech tree ful of boowis, and thei offriden there her sacrifices, and thei yauen there her offryngis, in to terring to wraththe; and thei settiden there the odour of her swetnesse, and thei offriden her moiste sacrifices.", "rotherham": "When I brought them into the land as to which I had lifted up mine hand to give it them, then beheld they every high hill and every tangled tree And offered there their sacrifices, And presented there, their provoking gift, And placed there, their satisfying odour, And poured out there, their drink- offerings.", "darby": "When I had brought them into the land which I had lifted up my hand to give unto them, then they saw every high hill and all the thick trees, and they offered there their sacrifices, and there they presented the provocation of their offering; and there they placed their sweet savour, and there poured out their drink-offerings.", "twenty": "", "jps": "For when I had brought them into the land, which I lifted up My hand to give unto them, then they saw every high hill, and every thick tree, and they offered there their sacrifices, and there they presented the provocation of their offering, there also they made their sweet savour, and there they poured out their drink-offerings.", "acv": "For when I had brought them into the land, which I swore to give to them, then they saw every high hill, and every thick tree, and they offered there their sacrifices, and there they presented the provocation of their offering. There also they made their sweet savor, and they poured out there their drink offerings.", "anderson": "", "haweis": "", "noyes": "For when I had brought them into the land concerning which I lifted up my hand, that I would give it to them, then they saw every high hill, and all the thick tree’s, and there they offered their sacrifices, and there they presented their provoking oblation, and there they brought their sweet savor, and there they poured out their drink-offerings.", "webster": "[For] when I had brought them into the land, [for] which I lifted up my hand to give it to them, then they saw every high hill, and all the thick trees, and they offered there their sacrifices, and there they presented the provocation of their offering: there also they made their sweet savor, and poured out there their drink-offerings.", "vulgate": "et induxissem eos in terram super quam levavi manum meam ut darem eis viderunt omnem collem excelsum et omne lignum nemorosum et immolaverunt ibi victimas suas et dederunt ibi inritationem oblationis suae et posuerunt ibi odorem suavitatis suae et libaverunt libationes suas;", "brenton": "Whereas I brought them into the land concerning which I lifted up mine hand to give it them; and they looked upon every high hill, and every shady tree, and they sacrificed there to their gods, and offered there sweet-smelling savour, and there they poured out their drink-offerings."}}, {"v": 29, "ref": "20:29", "o": "וָ/אֹמַ֣ר אֲלֵ/הֶ֔ם מָ֣ה הַ/בָּמָ֔ה אֲשֶׁר אַתֶּ֥ם הַ/בָּאִ֖ים שָׁ֑ם וַ/יִּקָּרֵ֤א שְׁמָ/הּ֙ בָּמָ֔ה עַ֖ד הַ/יּ֥וֹם הַ/זֶּֽה", "en": {"kjv": "Then I said unto them, What is the high place whereunto ye go? And the name thereof is called Bamah unto this day.", "web": "Then I said to them, What does the high place where you go mean? So its name is called Bamah to this day.", "bsb": "So I asked them: ‘What is this high place to which you go?’ (And to this day it is called Bamah.)", "asv": "Then I said unto them, What meaneth the high place whereunto ye go? So the name thereof is called Bamah unto this day.", "ylt": "And I say unto them: What is the high place whither ye are going in? And its name is called `high place' to this day.", "dra": "And I said to them: What meaneth the high place to which you go? and the name thereof was called High-place even to this day.", "bbe": "Then I said to them, What is this high place where you go to no purpose? And it is named Bamah to this day.", "geneva": "Then I saide vnto them, What is the hie place whereunto ye goe? And the name thereof was called Bamah vnto this day.", "wycliffe": "And Y seide to hem, What is the hiy thing, to whiche ye entren? And the name therof is clepid Hiy Thing til to this dai.", "rotherham": "Therefore said I unto them, What! a high-place, whereinto ye are entering? And so the name thereof hath been called High-place, until this day.", "darby": "And I said unto them, What is the high place whither ye go? And the name thereof is called Bamah unto this day.", "twenty": "", "jps": "Then I said unto them: What meaneth the high place whereunto ye go? So the name thereof is called Bamah unto this day.", "acv": "Then I said to them, What does the high place to which ye go mean? So the name of it is called Bamah to this day.", "anderson": "", "haweis": "", "noyes": "Then I said to them, What is the high place to which ye go? And it is called The High Place unto this day.", "webster": "Then I said to them, What [is] the high place to which ye go? and its name is called Bamah to this day.", "vulgate": "et dixi ad eos quid est excelsum ad quod vos ingredimini et vocatum est nomen eius Excelsum usque ad hanc diem;", "brenton": "And I said to them, What is Abama, that ye go in thither? and they called its name Abama, until this day."}}, {"v": 30, "ref": "20:30", "o": "לָ/כֵ֞ן אֱמֹ֣ר אֶל בֵּ֣ית יִשְׂרָאֵ֗ל כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הַ/בְּ/דֶ֥רֶךְ אֲבֽוֹתֵי/כֶ֖ם אַתֶּ֣ם נִטְמְאִ֑ים וְ/אַחֲרֵ֥י שִׁקּוּצֵי/הֶ֖ם אַתֶּ֥ם זֹנִֽים", "en": {"kjv": "Wherefore say unto the house of Israel, Thus saith the Lord God; Are ye polluted after the manner of your fathers? and commit ye whoredom after their abominations?", "web": "Therefore tell the house of Israel, Thus says the Lord Yahweh: Do you pollute yourselves in the way of your fathers? and do you play the prostitute after their abominations?", "bsb": "Therefore tell the house of Israel that this is what the Lord GOD says: Will you defile yourselves the way your fathers did, prostituting yourselves with their abominations?", "asv": "Wherefore say unto the house of Israel, Thus saith the Lord Jehovah: Do ye pollute yourselves after the manner of your fathers? and play ye the harlot after their abominations?", "ylt": "Therefore, say unto the house of Israel: Thus said the Lord Jehovah: In the way of your fathers are ye defiled? And after their detestable things go a-whoring?", "dra": "Wherefore say to the house of Israel: Thus saith the Lord God: Verily, you are defiled in the way of your fathers, and you commit fornication with their abominations.", "bbe": "For this cause say to the children of Israel, This is what the Lord has said: Are you making yourselves unclean as your fathers did? are you being untrue to me by going after their disgusting works?", "geneva": "Wherefore, say vnto the house of Israel, Thus saith the Lord God, Are ye not polluted after the maner of your fathers? and commit ye not whoredome after their abominations?", "wycliffe": "Therfor seie thou to the hous of Israel, The Lord God seith these thingis, Certis ye ben defoulid in the weie of youre fadris, and ye don fornycacioun aftir the offendingis of hem,", "rotherham": "Therefore say thou unto the house of Israel. Thus saith My Lord Yahweh, Is it in the way of your fathers, ye are defiling yourselves,- And after their abominations, that ye are committing lewdness?", "darby": "Therefore say unto the house of Israel, Thus saith the Lord Jehovah: Do ye defile yourselves after the manner of your fathers? and do ye commit fornication after their abominations?", "twenty": "", "jps": "Wherefore say unto the house of Israel: Thus saith the L-rd GOD: When ye pollute yourselves after the manner of your fathers, and go after their abominations,", "acv": "Therefore say to the house of Israel, Thus says the lord Jehovah: Do ye pollute yourselves according to the manner of your fathers, and play ye the harlot according to their abominations?", "anderson": "", "haweis": "", "noyes": "Therefore say to the house of Israel, Thus saith the Lord Jehovah: Are ye polluted after the manner of your fathers, and do ye commit fornication according to their abominations,", "webster": "Wherefore say to the house of Israel, Thus saith the Lord GOD; Are ye polluted after the manner of your fathers? and commit ye lewd deeds after their abominations?", "vulgate": "propterea dic ad domum Israhel haec dicit Dominus Deus certe in via patrum vestrorum vos polluimini et post offendicula eorum vos fornicamini;", "brenton": "Therefore say to the house of Israel, Thus saith the Lord, Do ye pollute yourselves with the iniquities of your fathers, and do ye go a-whoring after their abominations,"}}, {"v": 31, "ref": "20:31", "o": "וּ/בִ/שְׂאֵ֣ת מַתְּנֹֽתֵי/כֶ֡ם בְּֽ/הַעֲבִיר֩ בְּנֵי/כֶ֨ם בָּ/אֵ֜שׁ אַתֶּם֩ נִטְמְאִ֤֨ים לְ/כָל גִּלּֽוּלֵי/כֶם֙ עַד הַ/יּ֔וֹם וַ/אֲנִ֛י אִדָּרֵ֥שׁ לָ/כֶ֖ם בֵּ֣ית יִשְׂרָאֵ֑ל חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה אִם אִדָּרֵ֖שׁ לָ/כֶֽם", "en": {"kjv": "For when ye offer your gifts, when ye make your sons to pass through the fire, ye pollute yourselves with all your idols, even unto this day: and shall I be enquired of by you, O house of Israel? As I live, saith the Lord God, I will not be enquired of by you.", "web": "and when you offer your gifts, when you make your sons to pass through the fire, do you pollute yourselves with all your idols to this day? and shall I be inquired of by you, house of Israel? As I live, says the Lord Yahweh, I will not be inquired of by you;", "bsb": "When you offer your gifts, sacrificing your sons in the fire, you continue to defile yourselves with all your idols to this day. So should I be consulted by you, O house of Israel? As surely as I live, declares the Lord GOD, I will not be consulted by you!", "asv": "and when ye offer your gifts, when ye make your sons to pass through the fire, do ye pollute yourselves with all your idols unto this day? and shall I be inquired of by you, O house of Israel? As I live, saith the Lord Jehovah, I will not be inquired of by you;", "ylt": "And in the offering of your gifts, In causing your sons to pass through fire, Ye are defiled by all your idols to this day, And I am sought by you, O house of Israel! I live--an affirmation of the Lord Jehovah, I am not sought by you.", "dra": "And you defile yourselves with all your idols unto this day, in the offering of your gifts, when you make your children pass through the fire: and shall I answer you, O house of Israel? As I live, saith the Lord God, I will not answer you.", "bbe": "And when you give your offerings, causing your sons to go through the fire, you make yourselves unclean with all your images to this day; and will you come to me for directions, O children of Israel? By my life, says the Lord, you will get no direction from me.", "geneva": "For when you offer your giftes, and make your sonnes to passe through the fire, you pollute your selues with all your idoles vnto this day: shall I answere you when I am asked, O house of Israel? As I liue, saith the Lord God, I wil not answere you when I am asked.", "wycliffe": "and in the offryng of youre yiftis, whanne ye leden ouer youre sones bi fier, ye ben defoulid in alle youre idols til to dai, and schal Y answere to you, the hous of Israel? Y lyue, seith the Lord God, for Y schal not answere to you;", "rotherham": "Yea when ye lift up your gifts When ye cause your children to pass through the fire, Ye are defiling yourselves unto all your manufactured gods unto this day, And shall, I, be enquired of by you O house of Israel? As I live, Declareth My Lord Yahweh, Surely I will not be enquired of by you.", "darby": "And when ye offer your gifts, making your sons to pass through the fire, ye defile yourselves with all your idols, even unto this day; and shall I be inquired of by you, O house of Israel? [As] I live, saith the Lord Jehovah, I will not be inquired of by you.", "twenty": "", "jps": "and when, in offering your gifts, in making your sons to pass through the fire, ye pollute yourselves with all your idols, unto this day; shall I then be inquired of by you, O house of Israel? As I live, saith the L-rd GOD, I will not be inquired of by you;", "acv": "And when ye offer your gifts, when ye make your sons to pass through the fire, do ye pollute yourselves with all your idols to this day? And shall I be inquired of by you, O house of Israel? As I live, says the lord Jehovah, I will not be inquired of by you.", "anderson": "", "haweis": "", "noyes": "and by offering your gifts, and causing your sons to pass through the fire,—are ye polluted with all your idols even to this day, and shall I be inquired of by you, O house of Israel? As I live, saith the Lord Jehovah, I will not be inquired of by you!", "webster": "For when ye offer your gifts, when ye make your sons to pass through the fire, ye pollute yourselves with all your idols, even to this day: and shall I be inquired of by you, O house of Israel? [As] I live, saith the Lord GOD, I will not be inquired of by you.", "vulgate": "et in oblatione donorum vestrorum cum transducitis filios vestros per ignem vos polluimini in omnibus idolis vestris usque hodie et ego respondebo vobis domus Israhel vivo ego dicit Dominus Deus quia non respondebo vobis;", "brenton": "and do ye pollute yourselves with the first-fruits of your gifts, in the offerings wherewith ye pollute yourselves in all your imaginations, until this day; and shall I answer you, O house of Israel? As I live, saith the Lord, I will not answer you, neither shall this thing come upon your spirit."}}, {"v": 32, "ref": "20:32", "o": "וְ/הָֽ/עֹלָה֙ עַל ר֣וּחֲ/כֶ֔ם הָי֖וֹ לֹ֣א תִֽהְיֶ֑ה אֲשֶׁ֣ר אַתֶּ֣ם אֹמְרִ֗ים נִֽהְיֶ֤ה כַ/גּוֹיִם֙ כְּ/מִשְׁפְּח֣וֹת הָ/אֲרָצ֔וֹת לְ/שָׁרֵ֖ת עֵ֥ץ וָ/אָֽבֶן", "en": {"kjv": "And that which cometh into your mind shall not be at all, that ye say, We will be as the heathen, as the families of the countries, to serve wood and stone.", "web": "and that which comes into your mind shall not be at all, in that you say, We will be as the nations, as the families of the countries, to serve wood and stone.", "bsb": "When you say, ‘Let us be like the nations, like the peoples of the lands, serving wood and stone,’ what you have in mind will never come to pass.", "asv": "and that which cometh into your mind shall not be at all, in that ye say, We will be as the nations, as the families of the countries, to serve wood and stone.", "ylt": "And that which is going up on your mind, It is not at all--in that ye are saying: We will be as the nations, as the families of the lands, To serve wood and stone.", "dra": "Neither shall the thought of your mind come to pass, by which you say: We will be as the Gentiles, and as the families of the earth, to worship stocks and stones.", "bbe": "And that which comes into your minds will never take place; when you say, We will be like the nations, like the families of the countries, servants of wood and stone;", "geneva": "Neither shall that be done that commeth into your minde: for ye say, We wil be as the heathen, and as the families of the countreys, and serue wood, and stone.", "wycliffe": "nether the thouyte of youre soul schal be don, that seien, We schulen be as hethene men, and as naciouns of erthe, that we worschipe trees and stoonys.", "rotherham": "And as for that which is rising up on your spirit, it shall, not at all come to pass, In that ye are saying Let us be like the nations Like the families of the lands, By ministering unto Wood and Stone!", "darby": "And that which cometh into your mind shall not be at all, that ye say, We will be as the nations, as the families of the countries, in serving wood and stone.", "twenty": "", "jps": "and that which cometh into your mind shall not be at all; in that ye say: We will be as the nations, as the families of the countries, to serve wood and stone.", "acv": "And that which comes into your mind shall not be at all, in that ye say, We will be as the nations, as the families of the countries, to serve wood and stone.", "anderson": "", "haweis": "", "noyes": "And that which cometh into your mind shall not come to pass, when ye say, \"We will be as the nations, as the families of the countries, worshipping wood and stone.\"", "webster": "And that which cometh into your mind shall not be at all, that ye say, We will be as the heathen, as the families of the countries, to serve wood and stone.", "vulgate": "neque cogitatio mentis vestrae fiet dicentium erimus sicut gentes et sicut cognationes terrae ut colamus ligna et lapides;", "brenton": "And it shall not be as ye say, We will be as the nations, and as the tribes of the earth, to worship stocks and stones."}}, {"v": 33, "ref": "20:33", "o": "חַי אָ֕נִי נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה אִם לֹ֠א בְּ/יָ֨ד חֲזָקָ֜ה וּ/בִ/זְר֧וֹעַ נְטוּיָ֛ה וּ/בְ/חֵמָ֥ה שְׁפוּכָ֖ה אֶמְל֥וֹךְ עֲלֵי/כֶֽם", "en": {"kjv": "As I live, saith the Lord God, surely with a mighty hand, and with a stretched out arm, and with fury poured out, will I rule over you:", "web": "As I live, says the Lord Yahweh, surely with a mighty hand, and with an outstretched arm, and with wrath poured out, will I be king over you:", "bsb": "As surely as I live, declares the Lord GOD, with a strong hand, an outstretched arm, and outpoured wrath I will rule over you.", "asv": "As I live, saith the Lord Jehovah, surely with a mighty hand, and with an outstretched arm, and with wrath poured out, will I be king over you.", "ylt": "I live--an affirmation of the Lord Jehovah, Do not I, with a strong hand, And with a stretched-out arm, And with fury poured out--rule over you?", "dra": "As I live, saith the Lord God, I will reign over you with a strong hand, and with a stretched out arm, and with fury poured out.", "bbe": "By my life, says the Lord, truly, with a strong hand and with an outstretched arm and with burning wrath let loose, I will be King over you:", "geneva": "As I liue, saith the Lord God, I will surely rule you with a mightie hand, and with a stretched out arme, and in my wrath powred out,", "wycliffe": "Y lyue, seith the Lord God, for in strong hond, and in arm stretchid forth, and in strong veniaunce sched out, I schal regne on you.", "rotherham": "As I live, Declareth My Lord Yahweh, Surely, with a strong hand and With an outstretched arm and With outpoured indignation, Will I be king over you;", "darby": "[As] I live, saith the Lord Jehovah, verily with a mighty hand, and with an outstretched arm, and with fury poured out, will I reign over you.", "twenty": "", "jps": "As I live, saith the L-rd GOD, surely with a mighty hand, and with an outstretched arm, and with fury poured out, will I be king over you;", "acv": "As I live, says the lord Jehovah, surely with a mighty hand, and with an outstretched arm, and with wrath poured out, I will be king over you.", "anderson": "", "haweis": "", "noyes": "As I live, saith the Lord Jehovah, surely with a mighty hand, and with a stretched out arm, and with fury poured out will I rule over you.", "webster": "[As] I live, saith the Lord GOD, surely with a mighty hand, and with an out-stretched arm, and with fury poured out, will I rule over you:", "vulgate": "vivo ego dicit Dominus Deus quoniam in manu forti et brachio extento et in furore effuso regnabo super vos;", "brenton": "Therefore, as I live, saith the Lord, I will reign over you with a strong hand, and with a high arm, and with outpoured wrath:"}}, {"v": 34, "ref": "20:34", "o": "וְ/הוֹצֵאתִ֤י אֶתְ/כֶם֙ מִן הָ֣/עַמִּ֔ים וְ/קִבַּצְתִּ֣י אֶתְ/כֶ֔ם מִן הָ֣/אֲרָצ֔וֹת אֲשֶׁ֥ר נְפוֹצֹתֶ֖ם בָּ֑/ם בְּ/יָ֤ד חֲזָקָה֙ וּ/בִ/זְר֣וֹעַ נְטוּיָ֔ה וּ/בְ/חֵמָ֖ה שְׁפוּכָֽה", "en": {"kjv": "And I will bring you out from the people, and will gather you out of the countries wherein ye are scattered, with a mighty hand, and with a stretched out arm, and with fury poured out.", "web": "and I will bring you out from the peoples, and will gather you out of the countries in which you are scattered, with a mighty hand, and with an outstretched arm, and with wrath poured out;", "bsb": "With a strong hand, an outstretched arm, and outpoured wrath I will bring you out from the peoples and gather you from the lands to which you have been scattered.", "asv": "And I will bring you out from the peoples, and will gather you out of the countries wherein ye are scattered, with a mighty hand, and with an outstretched arm, and with wrath poured out;", "ylt": "And I have brought you forth from the peoples, And assembled you from the lands In which ye have been scattered, With a strong hand and with a stretched-out arm, And with fury poured out.", "dra": "And I will bring you out from the people, and I will gather you out of the countries, in which you are scattered, I will reign over you with a strong hand and with a stretched out arm, and with fury poured out.", "bbe": "And I will take you out from the peoples and get you together out of the countries where you are wandering, with a strong hand and with an outstretched arm and with burning wrath let loose:", "geneva": "And will bring you from the people, and will gather you out of the countreys, wherein ye are scattered, with a mighty hand, and with a stretched out arme, and in my wrath powred out,", "wycliffe": "And Y schal lede out you fro puplis, and Y schal gadere you fro londis, in whiche ye ben scaterid; in strong hond, and in arm stretchid forth, and in strong veniaunce sched out Y schal regne on you.", "rotherham": "And I will bring you forth from among the peoples, And gather you together out of the lands, throughout which ye have been dispersed, With a strong hand and With an outstretched arm, and With outpoured indignation;", "darby": "And I will bring you out from the peoples, and will gather you out of the countries wherein ye are scattered, with a mighty hand, and with an outstretched arm, and with fury poured out;", "twenty": "", "jps": "and I will bring you out from the peoples, and will gather you out of the countries wherein ye are scattered, with a mighty hand, and with an outstretched arm, and with fury poured out;", "acv": "And I will bring you out from the peoples, and will gather you out of the countries in which ye are scattered, with a mighty hand, and with an outstretched arm, and with wrath poured out,", "anderson": "", "haweis": "", "noyes": "And I will bring you forth from the nations, and gather you from the countries, wherein ye are scattered, with a mighty hand, and with a stretched out arm, and with fury poured out.", "webster": "And I will bring you out from the people, and will gather you out of the countries in which ye are scattered, with a mighty hand, and with an out-stretched arm, and with fury poured out.", "vulgate": "et educam vos de populis et congregabo vos de terris in quibus dispersi estis in manu valida et brachio extento et in furore effuso regnabo super vos;", "brenton": "I will bring you out from the nations, and will take you out of the lands wherein ye were dispersed, with a strong hand, and with a high arm, and with outpoured wrath."}}, {"v": 35, "ref": "20:35", "o": "וְ/הֵבֵאתִ֣י אֶתְ/כֶ֔ם אֶל מִדְבַּ֖ר הָֽ/עַמִּ֑ים וְ/נִשְׁפַּטְתִּ֤י אִתְּ/כֶם֙ שָׁ֔ם פָּנִ֖ים אֶל פָּנִֽים", "en": {"kjv": "And I will bring you into the wilderness of the people, and there will I plead with you face to face.", "web": "and I will bring you into the wilderness of the peoples, and there will I enter into judgment with you face to face.", "bsb": "And I will bring you into the wilderness of the nations, where I will enter into judgment with you face to face.", "asv": "and I will bring you into the wilderness of the peoples, and there will I enter into judgment with you face to face.", "ylt": "And I have brought you in unto the wilderness of the peoples, And have been judged with you there face to face.", "dra": "And I will bring you into the wilderness of people, and there will I plead with you face to face.", "bbe": "And I will take you into the waste land of the peoples, and there I will take up the cause with you face to face.", "geneva": "And I will bring you into the wildernes of the people, and there wil I pleade with you face to face.", "wycliffe": "And Y schal bringe you in to desert of puplis, and Y schal be demed there with you face to face.", "rotherham": "And I will bring you into the desert of the peoples,—and will contend with you there, face to face.", "darby": "and I will bring you into the wilderness of the peoples, and there will I enter into judgment with you face to face.", "twenty": "", "jps": "and I will bring you into the wilderness of the peoples, and there will I plead with you face to face.", "acv": "and I will bring you into the wilderness of the peoples. And there I will enter into judgment with you face to face.", "anderson": "", "haweis": "", "noyes": "And I will bring you into the desert of the nations, and there will I contend with you face to face.", "webster": "And I will bring you into the wilderness of the people, and there will I plead with you face to face.", "vulgate": "et adducam vos in desertum populorum et iudicabor vobiscum ibi facie ad faciem;", "brenton": "And I will bring you into the wilderness of the nations, and will plead with you there face to face."}}, {"v": 36, "ref": "20:36", "o": "כַּ/אֲשֶׁ֤ר נִשְׁפַּ֨טְתִּי֙ אֶת אֲב֣וֹתֵי/כֶ֔ם בְּ/מִדְבַּ֖ר אֶ֣רֶץ מִצְרָ֑יִם כֵּ֚ן אִשָּׁפֵ֣ט אִתְּ/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Like as I pleaded with your fathers in the wilderness of the land of Egypt, so will I plead with you, saith the Lord God.", "web": "Like as I entered into judgment with your fathers in the wilderness of the land of Egypt, so will I enter into judgment with you, says the Lord Yahweh.", "bsb": "Just as I entered into judgment with your fathers in the wilderness of the land of Egypt, so I will enter into judgment with you, declares the Lord GOD.", "asv": "Like as I entered into judgment with your fathers in the wilderness of the land of Egypt, so will I enter into judgment with you, saith the Lord Jehovah.", "ylt": "As I was judged with your fathers, In the wilderness of the land of Egypt, So I am judged with you, An affirmation of the Lord Jehovah.", "dra": "As I pleaded against your fathers in the desert of the land of Egypt; even so will I judge you, saith the Lord God.", "bbe": "As I took up the cause with your fathers in the waste land of the land of Egypt, so will I take up the cause with you says the Lord.", "geneva": "Like as I pleaded with your fathers in the wildernes of the lande of Egypt, so will I pleade with you, saith the Lord God.", "wycliffe": "As Y stryuede in doom ayens youre fadris in the desert of the lond of Egipt, so Y schal deme you, seith the Lord;", "rotherham": "Just as I contended with your fathers in the desert of the land of Egypt, So will I contend with you, Declareth My Lord Yahweh;", "darby": "Like as I entered into judgment with your fathers in the wilderness of the land of Egypt, so will I enter into judgment with you, saith the Lord Jehovah.", "twenty": "", "jps": "Like as I pleaded with your fathers in the wilderness of the land of Egypt, so will I plead with you, saith the L-rd GOD.", "acv": "Just as I entered into judgment with your fathers in the wilderness of the land of Egypt, so I will enter into judgment with you, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Even as I contended with your fathers in the desert of the land of Egypt, so also will I contend with you, saith the Lord Jehovah.", "webster": "As I pleaded with your fathers in the wilderness of the land of Egypt, so will I plead with you, saith the Lord GOD.", "vulgate": "sicut iudicio contendi adversum patres vestros in deserto terrae Aegypti sic iudicabo vos dicit Dominus Deus;", "brenton": "As I pleaded with your fathers in the wilderness of the land of Egypt, so will I judge you, saith the Lord."}}, {"v": 37, "ref": "20:37", "o": "וְ/הַעֲבַרְתִּ֥י אֶתְ/כֶ֖ם תַּ֣חַת הַ/שָּׁ֑בֶט וְ/הֵבֵאתִ֥י אֶתְ/כֶ֖ם בְּ/מָסֹ֥רֶת הַ/בְּרִֽית", "en": {"kjv": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant:", "web": "I will cause you to pass under the rod, and I will bring you into the bond of the covenant;", "bsb": "I will make you pass under the rod and will bring you into the bond of the covenant.", "asv": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant;", "ylt": "And I have caused you to pass under the rod, And brought you into the bond of the covenant,", "dra": "And I will make you subject to my sceptre, and will bring you into the bands of the covenant.", "bbe": "And I will make you go under the rod and will make you small in number:", "geneva": "And I wil cause you to passe vnder the rod, and wil bring you into the bond of the couenant.", "wycliffe": "and Y schal make you suget to my septre, and Y schal bringe in you in the boondis of pees.", "rotherham": "And I will cause you to pass under the rod And will bring you into the bond of the covenant;", "darby": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant.", "twenty": "", "jps": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant;", "acv": "And I will cause you to pass under the rod. And I will bring you into the bond of the covenant.", "anderson": "", "haweis": "", "noyes": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant.", "webster": "And I will cause you to pass under the rod, and I will bring you into the bond of the covenant.", "vulgate": "et subiciam vos sceptro meo et inducam vos in vinculis foederis;", "brenton": "And I will cause you to pass under my rod, and I will bring you in by number."}}, {"v": 38, "ref": "20:38", "o": "וּ/בָרוֹתִ֣י מִ/כֶּ֗ם הַ/מֹּרְדִ֤ים וְ/הַ/פּֽוֹשְׁעִים֙ בִּ֔/י מֵ/אֶ֤רֶץ מְגֽוּרֵי/הֶם֙ אוֹצִ֣יא אוֹתָ֔/ם וְ/אֶל אַדְמַ֥ת יִשְׂרָאֵ֖ל לֹ֣א יָב֑וֹא וִֽ/ידַעְתֶּ֖ם כִּי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will purge out from among you the rebels, and them that transgress against me: I will bring them forth out of the country where they sojourn, and they shall not enter into the land of Israel: and ye shall know that I am the Lord.", "web": "and I will purge out from among you the rebels, and those who disobey against me; I will bring them out of the land where they live, but they shall not enter into the land of Israel: and you shall know that I am Yahweh.", "bsb": "And I will purge you of those who rebel and transgress against Me. I will bring them out of the land in which they dwell, but they will not enter the land of Israel. Then you will know that I am the LORD.", "asv": "and I will purge out from among you the rebels, and them that transgress against me; I will bring them forth out of the land where they sojourn, but they shall not enter into the land of Israel: and ye shall know that I am Jehovah.", "ylt": "And cleared out from you the rebels, And them transgressing against Me, From the land of their sojournings I bring them out, And unto the land of Israel they come not, And ye have known that I am Jehovah.", "dra": "And I will pick out from among you the transgressors, and the wicked, and will bring them out of the land where they sojourn, and they shall not enter into the land of Israel: and you shall know that I am the Lord.", "bbe": "Clearing out from among you all those who are uncontrolled and who are sinning against me; I will take them out of the land where they are living, but they will not come into the land of Israel: and you will be certain that I am the Lord.", "geneva": "And I wil chuse out from among you the rebels, and them that transgresse against mee: I will bring them out of the land where they dwel, and they shall not enter into the lande of Israel, and you shall knowe that I am the Lord.", "wycliffe": "And Y schal chese of you trespassouris, and wickid men; and Y schal leede hem out of the lond of her dwelling, and thei schulen not entre in to the lond of Israel; and ye schulen wite, that Y am the Lord.", "rotherham": "And will sever from you those who are rebelling and those who are transgressing against me, Out of the land of their sojournings, will I bring them forth, Yet upon the soil of Israel, shall they not enter, So shall ye know that, I, am Yahweh.", "darby": "And I will purge out from among you the rebels, and them that transgress against me; I will bring them forth out of the country where they sojourn, but they shall not enter into the land of Israel: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "and I will purge out from among you the rebels, and them that transgress against Me; I will bring them forth out of the land where they sojourn, but they shall not enter into the land of Israel; and ye shall know that I am HaShem.", "acv": "And I will purge out from among you the rebels, and those who transgress against me. I will bring them forth out of the land where they sojourn, but they shall not enter into the land of Israel. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will purge out from among you the rebels, and them that transgress against me; out of the country where they sojourn will I bring them forth, but they shall not enter into the land of Israel; and ye shall know that I am Jehovah.", "webster": "And I will purge out from among you the rebels, and them that transgress against me: I will bring them forth out of the country where they sojourn, and they shall not enter into the land of Israel: and ye shall know that I [am] the LORD.", "vulgate": "et eligam de vobis transgressores et impios et de terra incolatus eorum educam eos et terram Israhel non ingredientur et scietis quia ego Dominus;", "brenton": "And I will separate from among you the ungodly and the revolters; for I will lead them forth out of their place of sojourning, and they shall not enter into the land of Israel: and ye shall know that I am the Lord, even the Lord."}}, {"v": 39, "ref": "20:39", "o": "וְ/אַתֶּ֨ם בֵּֽית יִשְׂרָאֵ֜ל כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה אִ֤ישׁ גִּלּוּלָי/ו֙ לְכ֣וּ עֲבֹ֔דוּ וְ/אַחַ֕ר אִם אֵינְ/כֶ֖ם שֹׁמְעִ֣ים אֵלָ֑/י וְ/אֶת שֵׁ֤ם קָדְשִׁ/י֙ לֹ֣א תְחַלְּלוּ ע֔וֹד בְּ/מַתְּנֽוֹתֵי/כֶ֖ם וּ/בְ/גִלּוּלֵי/כֶֽם", "en": {"kjv": "As for you, O house of Israel, thus saith the Lord God; Go ye, serve ye every one his idols, and hereafter also, if ye will not hearken unto me: but pollute ye my holy name no more with your gifts, and with your idols.", "web": "As for you, house of Israel, thus says the Lord Yahweh: Go, serve everyone his idols, and hereafter also, if you will not listen to me; but my holy name you shall no more profane with your gifts, and with your idols.", "bsb": "And as for you, O house of Israel, this is what the Lord GOD says: Go and serve your idols, every one of you. But afterward, you will surely listen to Me, and you will no longer defile My holy name with your gifts and idols.", "asv": "As for you, O house of Israel, thus saith the Lord Jehovah: Go ye, serve every one his idols, and hereafter also, if ye will not hearken unto me; but my holy name shall ye no more profane with your gifts, and with your idols.", "ylt": "And ye, O house of Israel, thus said the Lord Jehovah: Each his idols--go--serve ye, And, afterwards, if ye are not hearkening to me, And My holy name ye do not pollute any more by your gifts, and by your idols.", "dra": "And as for you, O house of Israel: thus saith the Lord God: Walk ye every one after your idols, and serve them. But if in this also you hear me not, but defile my holy name any more with your gifts, and with your idols;", "bbe": "As for you, O children of Israel, the Lord has said: Let every man completely put away his images and give ear to me: and let my holy name no longer be shamed by your offerings and your images.", "geneva": "As for you, O house of Israel, thus saith the Lord God, Goe you, and serue euery one his idole, seeing that ye will not obey me, and pollute mine holy Name no more with your giftes and with your idoles.", "wycliffe": "And ye, the hous of Israel, the Lord God seith these thingis, Go ye ech man aftir youre idols, and serue ye tho. That and if ye heren not me in this, and defoulen more myn hooli name in youre yiftis,", "rotherham": "But as for you, O house of Israel Thus, saith my Lord. Yahweh, Go. serve every man his own manufactured gods, Yet afterwards, surely Ye shall be ready to hearken unto me,— And my holy name, shall ye profane no more, With your gifts, and With your manufactured gods.", "darby": "As for you, O house of Israel, thus saith the Lord Jehovah: Go ye, serve every one his idols henceforth also, if none of you will hearken unto me; but profane my holy name no more with your gifts and with your idols.", "twenty": "", "jps": "As for you, O house of Israel, thus saith the L-rd GOD: Go ye, serve every one his idols, even because ye will not hearken unto Me; but My holy name shall ye no more profane with your gifts, and with your idols.", "acv": "As for you, O house of Israel, thus says the lord Jehovah: Go ye. Serve each one his idols, and hereafter also, if ye will not hearken to me. But ye shall no more profane my holy name with your gifts, and with your idols.", "anderson": "", "haweis": "", "noyes": "As for you, O house of Israel, thus saith the Lord Jehovah: Go ye, serve ye every one his idols in future also, if ye will not obey me! But pollute ye my holy name no more with your gifts and your idols!", "webster": "As for you, O house of Israel, thus saith the Lord GOD; Go ye, serve ye every one his idols, and hereafter [also], if ye will not hearken to me: but profane ye my holy name no more with your gifts, and with your idols.", "vulgate": "et vos domus Israhel haec dicit Dominus Deus singuli post idola vestra ambulate et servite eis quod si et in hoc non audieritis me et nomen meum sanctum pollueritis ultra in muneribus vestris et in idolis vestris;", "brenton": "And as to you, O house of Israel, thus saith the Lord, even the Lord; Put away each one his evil practices, and hereafter if ye hearken to me, then shall ye no more profane my holy name by your gifts and by devices."}}, {"v": 40, "ref": "20:40", "o": "כִּ֣י בְ/הַר קָדְשִׁ֞/י בְּ/הַ֣ר מְר֣וֹם יִשְׂרָאֵ֗ל נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה שָׁ֣ם יַעַבְדֻ֜/נִי כָּל בֵּ֧ית יִשְׂרָאֵ֛ל כֻּלֹּ֖/ה בָּ/אָ֑רֶץ שָׁ֣ם אֶרְצֵ֔/ם וְ/שָׁ֞ם אֶדְר֣וֹשׁ אֶת תְּרוּמֹֽתֵי/כֶ֗ם וְ/אֶת רֵאשִׁ֛ית מַשְׂאוֹתֵי/כֶ֖ם בְּ/כָל קָדְשֵׁי/כֶֽם", "en": {"kjv": "For in mine holy mountain, in the mountain of the height of Israel, saith the Lord God, there shall all the house of Israel, all of them in the land, serve me: there will I accept them, and there will I require your offerings, and the firstfruits of your oblations, with all your holy things.", "web": "For in my holy mountain, in the mountain of the height of Israel, says the Lord Yahweh, there shall all the house of Israel, all of them, serve me in the land: there will I accept them, and there will I require your offerings, and the first fruits of your offerings, with all your holy things.", "bsb": "For on My holy mountain, the high mountain of Israel, declares the Lord GOD, there the whole house of Israel, all of them, will serve Me in the land. There I will accept them and will require your offerings and choice gifts, along with all your holy sacrifices.", "asv": "For in my holy mountain, in the mountain of the height of Israel, saith the Lord Jehovah, there shall all the house of Israel, all of them, serve me in the land: there will I accept them, and there will I require your offerings, and the first-fruits of your oblations, with all your holy things.", "ylt": "For, in My holy mountain, In the mountain of the height of Israel, An affirmation of the Lord Jehovah, There serve Me do all the house of Israel, All of it, in the land--there I accept them, And there I do seek your heave-offerings, And with the first-fruit of your gifts, With all your holy things.", "dra": "In my holy mountain, in the high mountain of Israel, saith the Lord God, there shall all the house of Israel serve me; all of them I say, in the land in which they shall please me, and there will I require your firstfruits, and the chief of your tithes with all your sanctifications.", "bbe": "For in my holy mountain, in the high mountain of Israel, says the Lord, there all the children of Israel, all of them, will be my servants in the land; there I will take pleasure in them, and there I will be worshipped with your offerings and the first-fruits of the things you give, and with all your holy things.", "geneva": "For in mine holy mountaine, euen in the hie mountaine of Israel, saith the Lord God, there shall all the house of Israel, and all in the lande, serue me: there will I accept them, and there will I require your offrings and the first fruites of your oblations, with all your holy things.", "wycliffe": "and in youre idols, in myn hooli hil, in the hiy hil of Israel, seith the Lord God, ye schulen be punyschid greuousliere. There al the hous of Israel schal serue me, sotheli alle men in the lond, in which thei schulen plese me; and there Y schal seke youre firste fruytis, and the bigynnyng of youre tithis in alle youre halewyngis.", "rotherham": "For in my holy mountain. In the mountain of the height of Israel, Declareth, My Lord Yahweh, There shall all the house of Israel serve me, all of it, in the land, There will I accept them, and There, will I seek your heave-offerings and the firstfruits of your gifts, in all your holy things:", "darby": "For in my holy mountain, in the mountain of the height of Israel, saith the Lord Jehovah, there shall all the house of Israel serve me, the whole of it, in the land; there will I accept them, and there will I require your heave-offerings and the first-fruits of your offerings, with all your holy things.", "twenty": "", "jps": "For in My holy mountain, in the mountain of the height of Israel, saith the L-rd GOD, there shall all the house of Israel, all of them, serve Me in the land; there will I accept them, and there will I require your heave-offerings, and the first of your gifts, with all your holy things.", "acv": "For in my holy mountain, in the mountain of the height of Israel, says the lord Jehovah, there shall all the house of Israel, all of them, serve me in the land. There I will accept them, and there I will require your offerings, and the first-fruits of your oblations, with all your holy things.", "anderson": "", "haweis": "", "noyes": "For upon my holy mountain, upon the lofty mountain of Israel, there shall all the house of Israel, all that are in the land, serve me; there will I accept them, and there will I require your offerings, and the first fruits of your oblations, with all things which ye consecrate to me.", "webster": "For on my holy mountain, on the mountain of the hight of Israel, saith the Lord GOD, there shall all the house of Israel, all of them in the land, serve me: there will I accept them, and there will I require your offerings, and the first fruits of your oblations, with all your holy things.", "vulgate": "in monte sancto meo in monte excelso Israhel ait Dominus Deus ibi serviet mihi omnis domus Israhel omnes inquam in terra in qua placebunt mihi et ibi quaeram primitias vestras et initium decimarum vestrarum in omnibus sanctificationibus vestris;", "brenton": "For upon my holy mountain, on the high mountain, saith the Lord, even the Lord, there shall all the house of Israel serve me for ever: and there will I accept you, and there will I have respect to your first-fruits, and the first-fruits of your offerings, in all your holy things."}}, {"v": 41, "ref": "20:41", "o": "בְּ/רֵ֣יחַ נִיחֹחַ֮ אֶרְצֶ֣ה אֶתְ/כֶם֒ בְּ/הוֹצִיאִ֤/י אֶתְ/כֶם֙ מִן הָ֣/עַמִּ֔ים וְ/קִבַּצְתִּ֣י אֶתְ/כֶ֔ם מִן הָ֣/אֲרָצ֔וֹת אֲשֶׁ֥ר נְפֹצֹתֶ֖ם בָּ֑/ם וְ/נִקְדַּשְׁתִּ֥י בָ/כֶ֖ם לְ/עֵינֵ֥י הַ/גּוֹיִֽם", "en": {"kjv": "I will accept you with your sweet savour, when I bring you out from the people, and gather you out of the countries wherein ye have been scattered; and I will be sanctified in you before the heathen.", "web": "As a pleasant aroma will I accept you, when I bring you out from the peoples, and gather you out of the countries in which you have been scattered; and I will be sanctified in you in the sight of the nations.", "bsb": "When I bring you from the peoples and gather you from the lands to which you have been scattered, I will accept you as a pleasing aroma. And I will show My holiness through you in the sight of the nations.", "asv": "As a sweet savor will I accept you, when I bring you out from the peoples, and gather you out of the countries wherein ye have been scattered; and I will be sanctified in you in the sight of the nations.", "ylt": "With sweet fragrance I do accept you, In My bringing you out from the peoples, And I have assembled you from the lands In which ye have been scattered, And I have been sanctified in you Before the eyes of the nations.", "dra": "I will accept of you for an odour of sweetness, when I shall have brought you out from the people, and shall have gathered you out of the lands into which you are scattered, and I will be sanctified in you in the sight of the nations.", "bbe": "I will take pleasure in you as in a sweet smell, when I take you out from the peoples and get you together from the countries where you have been sent in flight; and I will make myself holy in you before the eyes of the nations.", "geneva": "I will accept your sweete sauour, when I bring you from the people, and gather you out of the countreys, wherein ye haue bene scattered, that I may be sanctified in you before ye heathen.", "wycliffe": "Y schal resseiue you in to odour of swetnesse, whanne Y schal leede you out of puplis, and schal gadere you fro londis, in whiche ye weren scaterid; and Y schal be halewid in you bifor the iyen of naciouns.", "rotherham": "As a satisfying odour, will I accept you, Through my bringing you forth from among the peoples, And gathering you out of the lands, throughout which ye have been dispersed; Thus will I hallow myself in you before the eyes of the nations.", "darby": "As a sweet savour will I accept you, when I bring you out from the peoples, and gather you out of the countries wherein ye have been scattered; and I will be hallowed in you in the sight of the nations.", "twenty": "", "jps": "With your sweet savour will I accept you, when I bring you out from the peoples, and gather you out of the countries wherein ye have been scattered; and I will be sanctified in you in the sight of the nations.", "acv": "I will accept you as a sweet savor when I bring you out from the peoples, and gather you out of the countries in which ye have been scattered. And I will be sanctified in you in the sight of the nations.", "anderson": "", "haweis": "", "noyes": "I will accept you as a sweet savor, when I bring you forth from the nations, and gather you from the countries, wherein ye have been scattered, and will through you be honored before the eyes of the nations.", "webster": "I will accept you with your sweet savor, when I bring you out from the people, and gather you out of the countries in which ye have been scattered; and I will be sanctified in you before the heathen.", "vulgate": "in odorem suavitatis suscipiam vos cum eduxero vos de populis et congregavero vos de terris in quas dispersi estis et sanctificabor in vobis in oculis nationum;", "brenton": "I will accept you with a sweet-smelling savour, when I bring you out from the nations, and take you out of the countries wherein ye have been dispersed; and I will be sanctified among you in the sight of the nations."}}, {"v": 42, "ref": "20:42", "o": "וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה בַּ/הֲבִיאִ֥/י אֶתְ/כֶ֖ם אֶל אַדְמַ֣ת יִשְׂרָאֵ֑ל אֶל הָ/אָ֗רֶץ אֲשֶׁ֤ר נָשָׂ֨אתִי֙ אֶת יָדִ֔/י לָ/תֵ֥ת אוֹתָ֖/הּ לַ/אֲבֽוֹתֵי/כֶֽם", "en": {"kjv": "And ye shall know that I am the Lord, when I shall bring you into the land of Israel, into the country for the which I lifted up mine hand to give it to your fathers.", "web": "You shall know that I am Yahweh, when I shall bring you into the land of Israel, into the country which I swore to give to your fathers.", "bsb": "Then you will know that I am the LORD, when I bring you into the land of Israel, the land that I swore to give your fathers.", "asv": "And ye shall know that I am Jehovah, when I shall bring you into the land of Israel, into the country which I sware to give unto your fathers.", "ylt": "And ye have known that I am Jehovah, In My bringing you to the ground of Israel, Unto the land that I did lift up My hand To give it to your fathers,", "dra": "And you shall know that I am the Lord, when I shall have brought you into the land of Israel, into the land for which I lifted up my hand to give it to your fathers.", "bbe": "And you will be certain that I am the Lord, when I take you into the land of Israel, into the country which I made an oath to give to your fathers.", "geneva": "And ye shall knowe, that I am the Lord, when I shall bring you into the land of Israel, into the land, for the which I lifted vp mine hande to giue it to your fathers.", "wycliffe": "And ye schulen wite, that Y am the Lord, whanne Y schal bringe you in to the lond of Israel, in to the lond for which Y reiside myn hond, that Y schulde yyue it to youre fadris.", "rotherham": "So shall ye know that I am Yahweh, Through my bringing you in unto the soil of Israel, Unto the land as to which I lifted up my hand, to give it unto your fathers.", "darby": "And ye shall know that I [am] Jehovah, when I have brought you into the land of Israel, into the country which I lifted up my hand to give to your fathers.", "twenty": "", "jps": "And ye shall know that I am HaShem, when I shall bring you into the land of Israel, into the country which I lifted up My hand to give unto your fathers.", "acv": "And ye shall know that I am Jehovah when I shall bring you into the land of Israel, into the country which I swore to give to your fathers.", "anderson": "", "haweis": "", "noyes": "And ye shall know that I am Jehovah, when I bring you into the land of Israel, into the country concerning which I lifted up my hand, that I would give it to your fathers.", "webster": "And ye shall know that I [am] the LORD, when I shall bring you into the land of Israel, into the country [for] which I lifted up my hand to give it to your fathers.", "vulgate": "et scietis quia ego Dominus cum induxero vos ad terram Israhel in terram pro qua levavi manum meam ut darem eam patribus vestris;", "brenton": "And ye shall know that I am the Lord, when I have brought you into the land of Israel, into the land concerning which I lifted up my hand to give it to your fathers."}}, {"v": 43, "ref": "20:43", "o": "וּ/זְכַרְתֶּם שָׁ֗ם אֶת דַּרְכֵי/כֶם֙ וְ/אֵת֙ כָּל עֲלִיל֣וֹתֵי/כֶ֔ם אֲשֶׁ֥ר נִטְמֵאתֶ֖ם בָּ֑/ם וּ/נְקֹֽטֹתֶם֙ בִּ/פְנֵי/כֶ֔ם בְּ/כָל רָעוֹתֵי/כֶ֖ם אֲשֶׁ֥ר עֲשִׂיתֶֽם", "en": {"kjv": "And there shall ye remember your ways, and all your doings, wherein ye have been defiled; and ye shall lothe yourselves in your own sight for all your evils that ye have committed.", "web": "There you shall remember your ways, and all your doings, in which you have polluted yourselves; and you shall loathe yourselves in your own sight for all your evils that you have committed.", "bsb": "There you will remember your ways and all the deeds with which you have defiled yourselves, and you will loathe yourselves for all the evils you have done.", "asv": "And there shall ye remember your ways, and all your doings, wherein ye have polluted yourselves; and ye shall loathe yourselves in your own sight for all your evils that ye have committed.", "ylt": "And ye have remembered there your ways, And all your doings, In which ye have been defiled, And ye have been loathsome in your own faces, For all your evils that ye have done.", "dra": "And there you shall remember your ways, and all your wicked doings with which you have been defiled; and you shall be displeased with yourselves in your own sight, for all your wicked deeds which you committed.", "bbe": "And there, at the memory of your ways and of all the things you did to make yourselves unclean, you will have bitter hate for yourselves because of all the evil things you have done.", "geneva": "And there shall ye remember your wayes, and all your workes, wherein ye haue bene defiled, and ye shall iudge your selues worthy to be cut off, for all your euils, that ye haue committed.", "wycliffe": "And ye schulen haue mynde there on youre weies, and on alle youre grete trespassis, bi whiche ye ben defoulid in tho; and ye schulen displese you in youre siyt, in alle youre malices whiche ye diden.", "rotherham": "Then shall ye call to mind. there, your own ways and all your own doings, wherewith ye had defiled yourselves,- And ye shall become loathsome in your own sight, for all your wickednesses, which ye have done.", "darby": "And there shall ye remember your ways, and all your doings, wherein ye have been defiled; and ye shall loathe yourselves in your own sight for all your evils which ye have committed.", "twenty": "", "jps": "And there shall ye remember your ways, and all your doings, wherein ye have polluted yourselves; and ye shall loathe yourselves in your own sight for all your evils that ye have committed.", "acv": "And there ye shall remember your ways, and all your doings, by which ye have polluted yourselves. And ye shall loathe yourselves in your own sight for all your evils that ye have committed.", "anderson": "", "haweis": "", "noyes": "And there shall ye remember your ways, and all your doings, wherein ye have been polluted; and ye shall loathe yourselves for all your evil deeds which ye have committed.", "webster": "And there shall ye remember your ways, and all your doings in which ye have been defiled; and ye shall lothe yourselves in your own sight for all your evils that ye have committed.", "vulgate": "et recordabimini ibi viarum vestrarum et omnium scelerum vestrorum quibus polluti estis in eis et displicebitis vobis in conspectu vestro in omnibus malitiis vestris quas fecistis;", "brenton": "And ye shall there remember your ways, and your devices wherewith ye defiled yourselves; and ye shall bewail yourselves for all your wickedness."}}, {"v": 44, "ref": "20:44", "o": "וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה בַּ/עֲשׂוֹתִ֥/י אִתְּ/כֶ֖ם לְמַ֣עַן שְׁמִ֑/י לֹא֩ כְ/דַרְכֵי/כֶ֨ם הָ/רָעִ֜ים וְ/כַ/עֲלִילֽוֹתֵי/כֶ֤ם הַ/נִּשְׁחָתוֹת֙ בֵּ֣ית יִשְׂרָאֵ֔ל נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And ye shall know that I am the Lord, when I have wrought with you for my name’s sake, not according to your wicked ways, nor according to your corrupt doings, O ye house of Israel, saith the Lord God.", "web": "You shall know that I am Yahweh, when I have dealt with you for my name’s sake, not according to your evil ways, nor according to your corrupt doings, you house of Israel, says the Lord Yahweh.", "bsb": "Then you will know, O house of Israel, that I am the LORD, when I have dealt with you for the sake of My name and not according to your wicked ways and corrupt acts, declares the Lord GOD.”", "asv": "And ye shall know that I am Jehovah, when I have dealt with you for my name’s sake, not according to your evil ways, nor according to your corrupt doings, O ye house of Israel, saith the Lord Jehovah.", "ylt": "And ye have known that I am Jehovah, In My dealing with you for My name's sake, Not according to your evil ways, And according to your corrupt doings, O house of Israel, An affirmation of the Lord Jehovah.'", "dra": "And you shall know that I am the Lord, when I shall have done well by you for my own name's sake, and not according to your evil ways, nor according to your wicked deeds, O house of Israel, saith the Lord God.", "bbe": "And you will be certain that I am the Lord, when I take you in hand for the honour of my name, and not for your evil ways or your unclean doings, O children of Israel, says the Lord.", "geneva": "And ye shall knowe, that I am the Lord, when I haue respect vnto you for my Names sake, and not after your wicked wayes, nor according to your corrupt workes, O ye house of Israel, saith the Lord God.", "wycliffe": "And ye schulen wite, that Y am the Lord, whanne Y schal do wel to you for my name; not bi youre yuel weies, nether bi youre worste trespassis, ye hous of Israel, seith the Lord God.", "rotherham": "So shall ye know that, I, am Yahweh, Through my dealing effectively with you, for the sake of mine own Name,- Not according to your own wicked ways. Nor according to your corrupted doings. O house of Israel, Declareth My Lord Yahweh.", "darby": "And ye shall know that I [am] Jehovah, when I have wrought with you for my name's sake, not according to your wicked ways, nor according to your corrupt doings, O house of Israel, saith the Lord Jehovah.", "twenty": "", "jps": "And ye shall know that I am HaShem, when I have wrought with you for My name's sake, not according to your evil ways, nor according to your corrupt doings, O ye house of Israel, saith the L-rd GOD.'", "acv": "And ye shall know that I am Jehovah when I have dealt with you for my name's sake, not according to your evil ways, nor according to your corrupt doings, O ye house of Israel, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And ye shall know that I am Jehovah, when I deal with you for my name’s sake, not according to your evil ways, nor according to your corrupt doings, O ye house of Israel, saith the Lord Jehovah.", "webster": "And ye shall know that I [am] the LORD, when I have wrought with you for my name's sake, not according to your wicked ways, nor according to your corrupt doings, O ye house of Israel, saith the Lord GOD.", "vulgate": "et scietis quia ego Dominus cum benefecero vobis propter nomen meum non secundum vias vestras malas neque secundum scelera vestra pessima domus Israhel ait Dominus Deus;", "brenton": "And ye shall know that I am the Lord, when I have done thus to you, that my name may not be profaned in your evil ways, and in your corrupt devices, saith the Lord."}}, {"v": 45, "ref": "20:45", "o": "", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Now the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moreouer, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me. saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 46, "ref": "20:46", "o": "", "en": {"kjv": "Son of man, set thy face toward the south, and drop thy word toward the south, and prophesy against the forest of the south field;", "web": "Son of man, set your face toward the south, and preach toward the south, and prophesy against the forest of the field in the South;", "bsb": "“Son of man, set your face toward the south, preach against it, and prophesy against the forest of the Negev.", "asv": "Son of man, set thy face toward the south, and drop thy word toward the south, and prophesy against the forest of the field in the South;", "ylt": "Son of man, set thy face the way of Teman, and prophesy unto the south, and prophesy unto the forest of the field--the south;", "dra": "Son of man, set thy face against the way of the south, and drop towards the south, and prophesy against the forest of the south field.", "bbe": "Son of man, let your face be turned to the south, let your words be dropped to the south, and be a prophet against the woodland of the South;", "geneva": "Sonne of man, set thy face toward the way of Teman, and drop thy word toward the South, and prophecie towarde the forest of the fielde of the South,", "wycliffe": "and he seide, Thou, sone of man, sette thi face ayens the weie of the south, and droppe thou to the south, and profesie thou to the forest of the myddai feeld.", "rotherham": "Son of man Set thy face the way towards Teman, And drop thy word against the land of the sun, And prophesy unto the forest of the field of the South;", "darby": "Son of man, set thy face toward the south, and drop [words] against the south, and prophesy against the forest of the south field;", "twenty": "", "jps": "", "acv": "Son of man, set thy face toward the south, and drop thy word toward the south, and prophesy against the forest of the field in the South.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face toward the south, and drop thy word against the South, and prophesy against the forest of the field in the South;", "webster": "Son of man, set thy face towards the south, and drop [thy word] towards the south, and prophesy against the forest of the south field;", "vulgate": "fili hominis pone faciem tuam contra viam austri et stilla ad africum et propheta ad saltum agri meridiani;", "brenton": "Son of man, set thy face against Thaeman, and look toward Darom, and prophesy against the chief forest of Nageb,"}}, {"v": 47, "ref": "20:47", "o": "", "en": {"kjv": "And say to the forest of the south, Hear the word of the Lord; Thus saith the Lord God; Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree: the flaming flame shall not be quenched, and all faces from the south to the north shall be burned therein.", "web": "and tell the forest of the South, Hear Yahweh’s word: Thus says the Lord Yahweh, Behold, I will kindle a fire in you, and it shall devour every green tree in you, and every dry tree: the flaming flame shall not be quenched, and all faces from the south to the north shall be burnt thereby.", "bsb": "Say to the forest of the Negev: Hear the word of the LORD! This is what the Lord GOD says: I am about to ignite in you a fire, and it will devour all your trees, both green and dry. The blazing flame will not be quenched, and by it every face from south to north will be scorched.", "asv": "and say to the forest of the South, Hear the word of Jehovah: Thus saith the Lord Jehovah, Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree: the flaming flame shall not be quenched, and all faces from the south to the north shall be burnt thereby.", "ylt": "and thou hast said to the forest of the south: Hear a word of Jehovah: Thus said the Lord Jehovah: Lo, I am kindling in thee a fire, And it hath devoured in thee every moist tree, and every dry tree, Not quenched is the glowing flames, And burnt by it have been all faces from south to north.", "dra": "And say to the south forest: Hear the word of the Lord: Thus saith the Lord God: Behold I will kindle a fire in thee, and will burn in thee every green tree, and every dry tree: the flame of the fire shall not be quenched: and every face shall be burned in it, from the south even to the north.", "bbe": "And say to the woodland of the South, Give ear to the words of the Lord: this is what the Lord has said: See, I will have a fire lighted in you, for the destruction of every green tree in you and every dry tree: the flaming flame will not be put out, and all faces from the south to the north will be burned by it.", "geneva": "And say to the forest of the South, Heare the worde of the Lord: thus saith the Lord God, Beholde, I will kindle a fire in thee, and it shall deuoure all the greene wood in thee, and all the drie wood: the continuall flame shall not bee quenched, and euery face from the South to the North shall be burnt therein.", "wycliffe": "And thou schalt seie to the myddai forest, Here thou the word of the Lord. The Lord God seith these thingis, Lo! Y schal kyndle a fier in thee, and Y schal brenne in thee ech green tre, and ech drie tre; the flawme of brennyng schal not be quenchid, and ech face schal be brent ther ynne, fro the south til to the north.", "rotherham": "And thou shalt say to the forest of the South Hear the word of Yahweh,— Thus saith My Lord Yahweh-Behold me! kindling in thee a fire. And it shall devour in thee every moist tree and every dry tree. The spreading flame shall not be quenched, Then shall be scorched thereby all faces from south to north;", "darby": "and say to the forest of the south, Hear the word of Jehovah. Thus saith the Lord Jehovah: Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree: the flashing flame shall not be quenched; and all that it meets from the south to the north shall be burned thereby.", "twenty": "", "jps": "", "acv": "And say to the forest of the South, Hear the word of Jehovah. Thus says the lord Jehovah: Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree. The flaming flame shall not be quenched, and all faces from the south to the north shall be burnt by it.", "anderson": "", "haweis": "", "noyes": "and say to the forest of the South, Hear the word of Jehovah! Thus saith the Lord Jehovah: Behold, I will kindle in thee a fire, which shall devour every green tree and every dry tree within thee; the fierce flame shall not be quenched, and all parts from the south to the north shall be burned therein.", "webster": "And say to the forest of the south, Hear the word of the LORD; Thus saith the Lord GOD; Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree: the flaming flame shall not be quenched, and all faces from the south to the north shall be burned therein.", "vulgate": "et dices saltui meridiano audi verbum Domini haec dicit Dominus Deus ecce ego succendam in te ignem et conburam in te omne lignum viride et omne lignum aridum non extinguetur flamma succensionis et conburetur in ea omnis facies ab austro usque ad aquilonem;", "brenton": "and thou shalt say to the forest of Nageb, Hear the word of the Lord; thus saith the Lord, even the Lord; Behold, I will kindle a fire in thee, and it shall devour in thee every green tree, and every dry tree: the flame that is kindled shall not be quenched, and every face shall be scorched with it from the south to the north."}}, {"v": 48, "ref": "20:48", "o": "", "en": {"kjv": "And all flesh shall see that I the Lord have kindled it: it shall not be quenched.", "web": "All flesh shall see that I, Yahweh, have kindled it; it shall not be quenched.", "bsb": "Then all people will see that I, the LORD, have kindled it; it will not be quenched.”", "asv": "And all flesh shall see that I, Jehovah, have kindled it; it shall not be quenched.", "ylt": "And seen have all flesh, that I, Jehovah, have kindled it--it is not quenched.'", "dra": "And all flesh shall see, that I the Lord have kindled it, and it shall not be quenched.", "bbe": "And all flesh will see that I the Lord have had it lighted: it will not be put out.", "geneva": "And all flesh shall see, that I the Lord haue kindled it, and it shall not bee quenched. Then saide I, Ah Lord God, they say of me, Doeth not he speake parables?", "wycliffe": "And ech man schal se, that Y the Lord haue kyndlid it, and it schal not be quenchid.", "rotherham": "And all flesh shall see that I. Yahweh have kindled it,- It shall not be quenched.", "darby": "And all flesh shall see that I Jehovah have kindled it: it shall not be quenched.", "twenty": "", "jps": "", "acv": "And all flesh shall see that I, Jehovah, have kindled it. It shall not be quenched.", "anderson": "", "haweis": "", "noyes": "And all flesh shall see that I, Jehovah, have kindled it; it shall not be quenched.", "webster": "And all flesh shall see that I the LORD have kindled it: it shall not be quenched.", "vulgate": "et videbit universa caro quia ego Dominus succendi eam nec extinguetur;", "brenton": "And all flesh shall know that I the Lord have kindled it: it shall not be quenched."}}, {"v": 49, "ref": "20:49", "o": "", "en": {"kjv": "Then said I, Ah Lord God! they say of me, Doth he not speak parables?", "web": "Then I said, Ah Lord Yahweh! they say of me, Isn’t he a speaker of parables?", "bsb": "Then I said, “Ah, Lord GOD, they are saying of me, ‘Is he not just telling parables?’”", "asv": "Then said I, Ah Lord Jehovah! they say of me, Is he not a speaker of parables?", "ylt": "And I say, `Ah, Lord Jehovah, They are saying of me, Is he not using similes?", "dra": "And I said: Ah, ah, ah, O Lord God: they say of me: Doth not this man speak by parables?", "bbe": "Then I said, Ah, Lord! they say of me, Is he not a maker of stories?", "geneva": "", "wycliffe": "And Y seide, A! A! A! Lord God, thei seien of me, Whethir this man spekith not bi parablis?", "rotherham": "Then said I, Ah! My Lord Yahweh: They are saying of me, Is not he a putter forth of parables?", "darby": "And I said, Ah, Lord Jehovah! they say of me, Doth he not speak parables?", "twenty": "", "jps": "", "acv": "Then I said, Ah lord Jehovah! They say of me, Is he not a speaker of parables?", "anderson": "", "haweis": "", "noyes": "And I said, Ah, Lord Jehovah, they say of me, \"Doth he not speak in parables?\"", "webster": "Then said I, Ah Lord GOD! they say of me, Doth he not speak parables?", "vulgate": "et dixi ha ha ha Domine Deus ipsi dicunt de me numquid non per parabolas loquitur iste;", "brenton": "And I said, Not so, O Lord God! they say to me, Is not this that is spoken a parable?"}}]}, {"c": 21, "verses": [{"v": 1, "ref": "21:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "The word of ye Lord came to me againe, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Then came the word of Jehovah to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "21:2", "o": "בֶּן אָדָ֗ם שִׂ֤ים פָּנֶ֨י/ךָ֙ דֶּ֣רֶךְ תֵּימָ֔נָ/ה וְ/הַטֵּ֖ף אֶל דָּר֑וֹם וְ/הִנָּבֵ֛א אֶל יַ֥עַר הַ/שָּׂדֶ֖ה נֶֽגֶב", "en": {"kjv": "Son of man, set thy face toward Jerusalem, and drop thy word toward the holy places, and prophesy against the land of Israel,", "web": "Son of man, set your face toward Jerusalem, and preach toward the sanctuaries, and prophesy against the land of Israel;", "bsb": "“Son of man, set your face against Jerusalem and preach against the sanctuaries. Prophesy against the land of Israel", "asv": "Son of man, set thy face toward Jerusalem, and drop thy word toward the sanctuaries, and prophesy against the land of Israel;", "ylt": "`Son of man, set thy face unto Jerusalem, and prophesy unto the holy places, and prophesy unto the ground of Israel;", "dra": "Son of man, set thy face toward Jerusalem, and let thy speech flow towards the holy places, and prophesy against the land of Israel:", "bbe": "Son of man, let your face be turned to Jerusalem, let your words be dropped in the direction of her holy place, and be a prophet against the land of Israel;", "geneva": "Sonne of man, set thy face toward Ierusalem, and drop thy word toward the holy places, and prophecie against the land of Israel.", "wycliffe": "and he seide, Thou, sone of man, sette thi face to Jerusalem, and droppe thou to the seyntuaries, and profesie thou ayens the erthe of Israel.", "rotherham": "Son of man Set thy face against Jerusalem, And drop thy word against the holy places And prophesy against the soil of Israel.", "darby": "Son of man, set thy face against Jerusalem, and drop [words] against the holy places, and prophesy against the land of Israel,", "twenty": "", "jps": "'Son of man, set thy face toward the South, and preach toward the South, and prophesy against the forest of the field in the South;", "acv": "Son of man, set thy face toward Jerusalem, and drop thy word toward the sanctuaries, and prophesy against the land of Israel.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face toward Jerusalem, and drop thy word toward the holy places, and prophesy against the land of Israel,", "webster": "Son of man, set thy face towards Jerusalem, and drop [thy word] towards the holy places, and prophesy against the land of Israel,", "vulgate": "fili hominis pone faciem tuam ad Hierusalem et stilla ad sanctuaria et propheta contra humum Israhel;", "brenton": "Therefore prophesy, son of man, set thy face steadfastly toward Jerusalem, and look toward their holy places, and thou shalt prophesy against the land of Israel,"}}, {"v": 3, "ref": "21:3", "o": "וְ/אָֽמַרְתָּ֙ לְ/יַ֣עַר הַ/נֶּ֔גֶב שְׁמַ֖ע דְּבַר יְהוָ֑ה כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֡ה הִנְ/נִ֣י מַֽצִּית בְּ/ךָ֣ אֵ֡שׁ וְ/אָכְלָ֣ה בְ/ךָ֣ כָל עֵֽץ לַח֩ וְ/כָל עֵ֨ץ יָבֵ֤שׁ לֹֽא תִכְבֶּה֙ לַהֶ֣בֶת שַׁלְהֶ֔בֶת וְ/נִצְרְבוּ בָ֥/הּ כָּל פָּנִ֖ים מִ/נֶּ֥גֶב צָפֽוֹנָ/ה", "en": {"kjv": "And say to the land of Israel, Thus saith the Lord; Behold, I am against thee, and will draw forth my sword out of his sheath, and will cut off from thee the righteous and the wicked.", "web": "and tell the land of Israel, Thus says Yahweh: Behold, I am against you, and will draw my sword out of its sheath, and will cut off from you the righteous and the wicked.", "bsb": "and tell her that this is what the LORD says: ‘I am against you, and I will draw My sword from its sheath and cut off from you both the righteous and the wicked.", "asv": "and say to the land of Israel, Thus saith Jehovah: Behold, I am against thee, and will draw forth my sword out of its sheath, and will cut off from thee the righteous and the wicked.", "ylt": "and thou hast said unto the ground of Israel: Thus said Jehovah: Lo, I am against thee, And have brought out My sword from its scabbard, And have cut off from thee righteous and wicked.", "dra": "And say to the land of Israel, Thus saith the Lord God: Behold I come against thee, and I will draw forth my sword out of its sheath, and will cut off in thee the just, and the wicked.", "bbe": "And say to the land of Israel, These are the words of the Lord: See, I am against you, and I will take my sword out of its cover, cutting off from you the upright and the evil.", "geneva": "And say to the land of Israel, Thus saith the Lord, Beholde, I come against thee, and will drawe my sword out of his sheath, and cut off from thee both the righteous and the wicked.", "wycliffe": "And thou schalt seie to the lond of Israel, The Lord God seith these thingis, Lo! Y to thee, and Y schal caste my swerd out of his schethe, and Y schal sle in thee a iust man and a wickid man.", "rotherham": "Thou shalt say then to the soil of Israel Thus saith Yahweh, Behold me against thee, Therefore will I bring forth my sword out of its sheath,—and will cut off from thee the righteous and the lawless.", "darby": "and say to the land of Israel, Thus saith Jehovah: Behold, I am against thee, and I will draw forth my sword out of its sheath, and will cut off from thee the righteous and the wicked.", "twenty": "", "jps": "and say to the forest of the South: Hear the word of HaShem: Thus saith the L-rd GOD: Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree, it shall not be quenched, even a flaming flame; and all faces from the south to the north shall be seared thereby.", "acv": "And say to the land of Israel, Thus says Jehovah: Behold, I am against thee. And will draw forth my sword out of its sheath, and will cut off from thee the righteous and the wicked.", "anderson": "", "haweis": "", "noyes": "and say to the land of Israel, Thus saith Jehovah: Behold, I am against thee, and I will draw forth my sword out of its sheath, and will cut off from thee the righteous and the wicked.", "webster": "And say to the land of Israel, Thus saith the LORD; Behold, I [am] against thee, and will draw forth my sword out of its sheath, and will cut off from thee the righteous and the wicked.", "vulgate": "et dices terrae Israhel haec dicit Dominus Deus ecce ego ad te et eiciam gladium meum de vagina sua et occidam in te iustum et impium;", "brenton": "and thou shalt say to the land of Israel, Thus saith the Lord; Behold, I am against thee, and I will draw forth my sword out of its sheath, and I will destroy out of thee the transgressor and unrighteous."}}, {"v": 4, "ref": "21:4", "o": "וְ/רָאוּ֙ כָּל בָּשָׂ֔ר כִּ֛י אֲנִ֥י יְהוָ֖ה בִּֽעַרְתִּ֑י/הָ לֹ֖א תִּכְבֶּֽה", "en": {"kjv": "Seeing then that I will cut off from thee the righteous and the wicked, therefore shall my sword go forth out of his sheath against all flesh from the south to the north:", "web": "Seeing then that I will cut off from you the righteous and the wicked, therefore shall my sword go out of its sheath against all flesh from the south to the north:", "bsb": "Because I will cut off both the righteous and the wicked, My sword will be unsheathed against everyone from south to north.", "asv": "Seeing then that I will cut off from thee the righteous and the wicked, therefore shall my sword go forth out of its sheath against all flesh from the south to the north:", "ylt": "Because that I have cut off from thee righteous and wicked, Therefore go out doth My sword from its scabbard, Unto all flesh, from south to north.", "dra": "And forasmuch as I have cut off in thee the just and the wicked, therefore shall my sword go forth out of its sheath against all flesh, from the south even to the north.", "bbe": "Because I am going to have the upright and the evil cut off from you, for this cause my sword will go out from its cover against all flesh from the south to the north:", "geneva": "Seeing then that I will cut off from thee both the righteous and wicked, therefore shall my sworde goe out of his sheath against all flesh from the South to the North,", "wycliffe": "Forsothe for that that Y haue slayn in thee a iust man and a wickid man, therfor my swerd schal go out of his schethe to ech man, fro the south til to the north;", "rotherham": "Because I have cut off from thee the righteous and the lawless, Therefore shall my sword go forth out of its sheath against all flesh from south to north:", "darby": "Seeing that I will cut off from thee the righteous and the wicked, therefore shall my sword go forth out of its sheath against all flesh, from the south to the north;", "twenty": "", "jps": "And all flesh shall see that I HaShem have kindled it; it shall not be quenched.'", "acv": "Seeing then that I will cut off from thee the righteous and the wicked, therefore my sword shall go forth out of its sheath against all flesh from the south to the north.", "anderson": "", "haweis": "", "noyes": "Seeing then that I cut off from thee the righteous and the wicked, therefore shall my sword go forth out of its sheath against all flesh from the south to the north.", "webster": "Seeing then that I will cut off from thee the righteous and the wicked, therefore shall my sword go forth from its sheath against all flesh from the south to the north:", "vulgate": "pro eo autem quod occidi in te iustum et impium idcirco egredietur gladius meus de vagina sua ad omnem carnem ab austro ad aquilonem;", "brenton": "Because I will destroy out of thee the unrighteous and the transgressor, therefore so shall my sword come forth out of its sheath against all flesh from the south to the north:"}}, {"v": 5, "ref": "21:5", "o": "וָ/אֹמַ֕ר אֲהָ֖הּ אֲדֹנָ֣/י יְהוִ֑ה הֵ֚מָּה אֹמְרִ֣ים לִ֔/י הֲ/לֹ֛א מְמַשֵּׁ֥ל מְשָׁלִ֖ים הֽוּא", "en": {"kjv": "That all flesh may know that I the Lord have drawn forth my sword out of his sheath: it shall not return any more.", "web": "and all flesh shall know that I, Yahweh, have drawn my sword out of its sheath; it shall not return any more.", "bsb": "Then all flesh will know that I, the LORD, have taken My sword from its sheath, not to return it again.’", "asv": "and all flesh shall know that I, Jehovah, have drawn forth my sword out of its sheath; it shall not return any more.", "ylt": "And known have all flesh that I, Jehovah, Have brought out My sword from its scabbard, It doth not turn back any more.", "dra": "That all flesh may know that I the Lord have drawn my sword out of its sheath not to be turned back.", "bbe": "And all flesh will see that I the Lord have taken my sword out of its cover: and it will never go back.", "geneva": "That all flesh may knowe that I the Lord haue drawen my sworde out of his sheath, and it shall not returne any more.", "wycliffe": "that ech man wite, that Y the Lord haue drawe out my swerd fro his schethe, that schal not be clepid ayen.", "rotherham": "So shall all flesh know that, I, Yahweh have brought forth my sword out of its sheath,— it shall not return any more.", "darby": "and all flesh shall know that I Jehovah have drawn forth my sword out of its sheath: it shall not return any more.", "twenty": "", "jps": "Then said I: 'Ah L-rd GOD! they say of me: Is he not a maker of parables?'", "acv": "And all flesh shall know that I, Jehovah, have drawn forth my sword out of its sheath. It shall not return any more.", "anderson": "", "haweis": "", "noyes": "And all flesh shall know that I, Jehovah, have drawn forth my sword out of its sheath; it shall not return any more.", "webster": "That all flesh may know that I the LORD have drawn my sword out of its sheath: it shall not return any more.", "vulgate": "ut sciat omnis caro quia ego Dominus eduxi gladium meum de vagina sua inrevocabilem;", "brenton": "and all flesh shall know that I the Lord have drawn forth my sword out of its sheath: it shall not return any more."}}, {"v": 6, "ref": "21:6", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Sigh therefore, thou son of man, with the breaking of thy loins; and with bitterness sigh before their eyes.", "web": "Sigh therefore, you son of man; with the breaking of your thighs and with bitterness you will sigh before their eyes.", "bsb": "But you, son of man, groan! Groan before their eyes with a broken heart and bitter grief.", "asv": "Sigh therefore, thou son of man; with the breaking of thy loins and with bitterness shalt thou sigh before their eyes.", "ylt": "And thou, son of man, sigh with breaking of loins, yea, with bitterness thou dost sigh before their eyes,", "dra": "And thou, son of man, mourn with the breaking of thy loins, and with bitterness sigh before them.", "bbe": "Make sounds of grief, son of man; with body bent and a bitter heart make sounds of grief before their eyes.", "geneva": "Mourne therefore, thou sonne of man, as in the paine of thy reines, and mourne bitterly before them.", "wycliffe": "And thou, sone of man, weile in sorewe of leendis, and in bitternessis thou schalt weile bifore hem.", "rotherham": "Thou, therefore O son of man sigh,— In the sharp pain of thy loins and in bitterness, shalt thou sigh before their eyes.", "darby": "Sigh then, thou son of man; with breaking of the loins, and with bitterness sigh before their eyes.", "twenty": "", "jps": "Then the word of HaShem came unto me, saying:", "acv": "Sigh therefore, thou son of man. With the breaking of thy loins and with bitterness thou shall sigh before their eyes.", "anderson": "", "haweis": "", "noyes": "Thou, therefore, O son of man, sigh! With the breaking of thy loins, and with bitterness, sigh before their eyes!", "webster": "Sigh therefore, thou son of man, with the breaking of [thy] loins; and with bitterness sigh before their eyes.", "vulgate": "et tu fili hominis ingemesce in contritione lumborum et in amaritudinibus ingemesce coram eis;", "brenton": "And thou, son of man, groan with the breaking of thy loins; thou shalt even groan heavily in their sight."}}, {"v": 7, "ref": "21:7", "o": "בֶּן אָדָ֗ם שִׂ֤ים פָּנֶ֨י/ךָ֙ אֶל יְר֣וּשָׁלִַ֔ם וְ/הַטֵּ֖ף אֶל מִקְדָּשִׁ֑ים וְ/הִנָּבֵ֖א אֶל אַדְמַ֥ת יִשְׂרָאֵֽל", "en": {"kjv": "And it shall be, when they say unto thee, Wherefore sighest thou? that thou shalt answer, For the tidings; because it cometh: and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak as water: behold, it cometh, and shall be brought to pass, saith the Lord God.", "web": "It shall be, when they tell you, Why do you sigh? that you shall say, Because of the news, for it comes; and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak as water: behold, it comes, and it shall be done, says the Lord Yahweh.", "bsb": "And when they ask, ‘Why are you groaning?’ you are to say, ‘Because of the news that is coming. Every heart will melt, and every hand will go limp. Every spirit will faint, and every knee will turn to water.’ Yes, it is coming and it will surely happen, declares the Lord GOD.”", "asv": "And it shall be, when they say unto thee, Wherefore sighest thou? that thou shalt say, Because of the tidings, for it cometh; and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak as water: behold, it cometh, and it shall be done, saith the Lord Jehovah.", "ylt": "and it hath come to pass, when they say unto thee, For what art thou sighing? that thou hast said: Because of the report, for it is coming, And melted hath every heart, And feeble hath been all hands, And weak is every spirit, And all knees go--waters, Lo, it is coming, yea, it hath been, An affirmation of the Lord Jehovah.'", "dra": "And when they shall say to thee: Why mournest thou? thou shalt say: For that which I hear: because it cometh, and every heart shall melt, and all hands shall be made feeble, and every spirit shall faint, and water shall run down every knee: behold it cometh, and it shall be done, saith the Lord God.", "bbe": "And when they say to you, Why are you making sounds of grief? then say, Because of the news, for it is coming: and every heart will become soft, and all hands will be feeble, and every spirit will be burning low, and all knees will be turned to water: see, it is coming and it will be done, says the Lord.", "geneva": "And if they say vnto thee, Wherefore mournest thou? then answere, Because of the bruite: for it commeth, and euery heart shall melt, and all handes shall be weake, and all mindes shall faint, and all knees shall fall away as water: beholde, it commeth, and shall be done, saith the Lord God.", "wycliffe": "And whanne thei schulen seie to thee, Whi weilist thou? thou schalt seie, For hering, for it cometh; and ech herte shal faile, and alle hondis schulen be aclumsid, and ech spirit schal be sike, and watris schulen flete doun bi alle knees; lo! it cometh, and it shal be don, seith the Lord God.", "rotherham": "And it shall come to pass when they shall say unto thee, Wherefore art thou sighing? that thou shalt say, For the report because it cometh, When every heart shall melt. And all hands be unnerved And every spirit shall become faint. And all knees shall be weak as water, Lo! it cometh and shall be brought to pass, Saith My Lord, Yahweh.", "darby": "And it shall be, when they say unto thee, Wherefore dost thou sigh? that thou shalt say, Because of the tidings, for it cometh; and every heart shall melt, and all hands shall be feeble, and every spirit shall languish, and all knees shall melt into water: behold, it cometh; it is here, saith the Lord Jehovah.", "twenty": "", "jps": "'Son of man, set thy face toward Jerusalem, and preach toward the sanctuaries, and prophesy against the land of Israel;", "acv": "And it shall be, when they say to thee, Why do thou sigh? That thou shall say, Because of the news. For it comes, and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak as water. Behold, it comes, and it shall be done, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And when they shall say to thee, \"Wherefore sighest thou?\" thou shalt say, \"For the rumor, because it cometh; and every heart shall melt, and all hands shall be feeble, and every spirit shall fail, and all knees shall flow with water. Behold it cometh, it shall be brought to pass, saith the Lord Jehovah.\"", "webster": "And it shall be, when they say to thee, Why sighest thou? that thou shalt answer, For the tidings; because it cometh: and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak [as] water: behold, it cometh, and shall be brought to pass, saith the Lord GOD.", "vulgate": "cumque dixerint ad te quare tu gemis dices pro auditu quia venit et tabescet omne cor et dissolventur universae manus et infirmabitur omnis spiritus et per cuncta genua fluent aquae ecce venit et fiet ait Dominus Deus;", "brenton": "And it shall come to pass, if they shall say to thee, Wherefore dost thou groan? that thou shalt say, For the report; because it comes: and every heart shall break, and all hands shall become feeble, and all flesh and every spirit shall faint, and all thighs shall be defiled with moisture: behold, it comes, saith the Lord."}}, {"v": 8, "ref": "21:8", "o": "וְ/אָמַרְתָּ֞ לְ/אַדְמַ֣ת יִשְׂרָאֵ֗ל כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְ/נִ֣י אֵלַ֔יִ/ךְ וְ/הוֹצֵאתִ֥י חַרְבִּ֖/י מִ/תַּעְרָ֑/הּ וְ/הִכְרַתִּ֥י מִמֵּ֖/ךְ צַדִּ֥יק וְ/רָשָֽׁע", "en": {"kjv": "Again the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Againe, the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me. saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "and say to the land of Israel: Thus saith HaShem: Behold, I am against thee, and will draw forth My sword out of its sheath, and will cut off from thee the righteous and the wicked.", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Also the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 9, "ref": "21:9", "o": "יַ֛עַן אֲשֶׁר הִכְרַ֥תִּי מִמֵּ֖/ךְ צַדִּ֣יק וְ/רָשָׁ֑ע לָ֠/כֵן תֵּצֵ֨א חַרְבִּ֧/י מִ/תַּעְרָ֛/הּ אֶל כָּל בָּשָׂ֖ר מִ/נֶּ֥גֶב צָפֽוֹן", "en": {"kjv": "Son of man, prophesy, and say, Thus saith the Lord; Say, A sword, a sword is sharpened, and also furbished:", "web": "Son of man, prophesy, and say, Thus says Yahweh: Say, A sword, a sword, it is sharpened, and also furbished;", "bsb": "“Son of man, prophesy and tell them that this is what the Lord says: ‘A sword, a sword, sharpened and polished—", "asv": "Son of man, prophesy, and say, Thus saith Jehovah: Say, A sword, a sword, it is sharpened, and also furbished;", "ylt": "`Son of man, prophesy, and thou hast said, Thus said Jehovah, say: A sword, a sword is sharpened, and also polished.", "dra": "Son of man, prophesy, and say: Thus saith the Lord God: Say: The sword, the sword is sharpened, and furbished.", "bbe": "Son of man, say as a prophet, These are the words of the Lord: Say, A sword, a sword which has been made sharp and polished:", "geneva": "Sonne of man, prophecie, and say, Thus saith the Lord God, say, A sworde, a sworde both sharpe, and fourbished.", "wycliffe": "and he seide, Sone of man, profesie thou; and thou schalt seie, The Lord God seith these thingis, Speke thou, The swerd, the swerd is maad scharp, and is maad briyt;", "rotherham": "Son of man, Prophesy and thou shalt say, Thus saith My Lord,— Say, A sword! a sword! Sharpened moreover also furbished:", "darby": "Son of man, prophesy, and say, Thus saith Jehovah: Say, A sword, a sword is sharpened, and also furbished.", "twenty": "", "jps": "Seeing then that I will cut off from thee the righteous and the wicked, therefore shall My sword go forth out of its sheath against all flesh from the south to the north;", "acv": "Son of man, prophesy, and say, Thus says Jehovah: Say, A sword, a sword. It is sharpened, and also furbished.", "anderson": "", "haweis": "", "noyes": "Son of man, prophesy, and say, Thus saith Jehovah: Say, The sword, the sword is sharpened and furbished.", "webster": "Son of man, prophesy, and say, Thus saith the LORD; Say, A sword, a sword is sharpened, and also furbished:", "vulgate": "fili hominis propheta et dices haec dicit Dominus Deus loquere gladius gladius exacutus est et limatus;", "brenton": "Son of man, prophesy, and thou shalt say, Thus saith the Lord; Say, Sword, sword, be sharpened and rage,"}}, {"v": 10, "ref": "21:10", "o": "וְ/יָֽדְעוּ֙ כָּל בָּשָׂ֔ר כִּ֚י אֲנִ֣י יְהוָ֔ה הוֹצֵ֥אתִי חַרְבִּ֖/י מִ/תַּעְרָ֑/הּ לֹ֥א תָשׁ֖וּב עֽוֹד", "en": {"kjv": "It is sharpened to make a sore slaughter; it is furbished that it may glitter: should we then make mirth? it contemneth the rod of my son, as every tree.", "web": "it is sharpened that it may make a slaughter; it is furbished that it may be as lightning: shall we then make mirth? the rod of my son, it condemns every tree.", "bsb": "it is sharpened for the slaughter, polished to flash like lightning! Should we rejoice in the scepter of My son? The sword despises every such stick.", "asv": "it is sharpened that it may make a slaughter; it is furbished that it may be as lightning: shall we then make mirth? the rod of my son, it contemneth every tree.", "ylt": "So as to slaughter a slaughter it is sharpened. So as to have brightness it is polished, Desire hath rejoiced the sceptre of my son, It is despising every tree.", "dra": "It is sharpened to kill victims: it is furbished that it may glitter: thou removest the sceptre of my son, thou hast cut down every tree.", "bbe": "It has been made sharp to give death; it is polished so that it may be like a thunder-flame: ...", "geneva": "It is sharpened to make a sore slaughter, and it is fourbished that it may glitter: how shall we reioyce? for it contemneth the rod of my sonne, as all other trees.", "wycliffe": "it is maad scharp to sle sacrifices; it is maad briyt, that it schyne. Thou that mouest the ceptre of my sone, hast kit doun ech tree.", "rotherham": "To make a slaughter, is it sharpened, That it may flash as lightning, is it furbished. Or shall we flourish the royal rod of my son which despiseth every tree?", "darby": "It is sharpened for sore slaughter, it is furbished that it may glitter. Shall we then make mirth, [saying,] The sceptre of my son contemneth all wood?", "twenty": "", "jps": "and all flesh shall know that I HaShem have drawn forth My sword out of its sheath; it shall not return any more.", "acv": "It is sharpened that it may make a slaughter. It is polished that it may be as lightning. Shall we then make mirth? It scorns the scepter of my son, every tree.", "anderson": "", "haweis": "", "noyes": "It is sharpened, that it may make sore slaughter; it is furbished that it may glitter. Or shall we make mirth? The staff of my son despiseth every rod.", "webster": "It is sharpened to make a grievous slaughter; it is furbished that it may glitter: should we then make mirth? it contemneth the rod of my son, [as] every tree.", "vulgate": "ut caedat victimas exacutus est ut splendeat limatus est qui moves sceptrum filii mei succidisti omne lignum;", "brenton": "that thou mayest slay victims; be sharpened that thou mayest be bright, ready for slaughter, slay, set at nought, despise every tree."}}, {"v": 11, "ref": "21:11", "o": "וְ/אַתָּ֥ה בֶן אָדָ֖ם הֵֽאָנַ֑ח בְּ/שִׁבְר֤וֹן מָתְנַ֨יִם֙ וּ/בִ/מְרִיר֔וּת תֵּֽאָנַ֖ח לְ/עֵינֵי/הֶֽם", "en": {"kjv": "And he hath given it to be furbished, that it may be handled: this sword is sharpened, and it is furbished, to give it into the hand of the slayer.", "web": "It is given to be furbished, that it may be handled: the sword, it is sharpened, yes, it is furbished, to give it into the hand of the killer.", "bsb": "The sword is appointed to be polished, to be grasped in the hand. It is sharpened and polished, to be placed in the hand of the slayer.", "asv": "And it is given to be furbished, that it may be handled: the sword, it is sharpened, yea, it is furbished, to give it into the hand of the slayer.", "ylt": "And he giveth it for polishing, For laying hold of by the hand. It is sharpened--the sword--and polished, To give it into the hand of a slayer.", "dra": "And I have given it to be furbished, that it may be handled: this sword is sharpened, and it is furbished, that it may be in the hand of the slayer.", "bbe": "And I have given it to the polisher so that it may be taken in the hand: he has made the sword sharp, he has had it polished, to put it into the hand of him who gives death.", "geneva": "And he hath giuen it to be fourbished, that he may handle it: this sword is sharpe, and is fourbished, that he may giue it into ye hand of the slayer.", "wycliffe": "And Y yaf it to be forbischid, that it be holdun with hond; this swerd is maad scharp, and this is maad briyt, that it be in the hond of the sleere.", "rotherham": "It hath. however been given to be furbished that it may be grasped by the hand:The same is a sword sharpened. Yea the same, is furbished, Ready to be given into the hand of the slayer.", "darby": "And he hath given it to be furbished that it may be handled. The sword, — it is sharpened, and it is furbished to give it into the hand of the slayer.", "twenty": "", "jps": "Sigh therefore, thou son of man; with the breaking of thy loins and with bitterness shalt thou sigh before their eyes.", "acv": "And it is given to be polished, that it may be handled. The sword, it is sharpened, yea, it is polished, to give it into the hand of the slayer.", "anderson": "", "haweis": "", "noyes": "And he gave it to be furbished that it might be handled. The sword is sharpened and furbished, to be given into the hand of the slayer.", "webster": "And he hath given it to be furbished, that it may be handled: the sword is sharpened, and it is furbished, to give it into the hand of the slayer.", "vulgate": "et dedi eum ad levigandum ut teneatur manu iste exacutus est gladius et iste limatus ut sit in manu interficientis;", "brenton": "And he made it ready for his hand to hold: the sword is sharpened, it is ready to put into the hand of the slayer."}}, {"v": 12, "ref": "21:12", "o": "וְ/הָיָה֙ כִּֽי יֹאמְר֣וּ אֵלֶ֔י/ךָ עַל מָ֖ה אַתָּ֣ה נֶאֱנָ֑ח וְ/אָמַרְתָּ֡ אֶל שְׁמוּעָ֣ה כִֽי בָאָ֡ה וְ/נָמֵ֣ס כָּל לֵב֩ וְ/רָפ֨וּ כָל יָדַ֜יִם וְ/כִהֲתָ֣ה כָל ר֗וּחַ וְ/כָל בִּרְכַּ֨יִם֙ תֵּלַ֣כְנָה מַּ֔יִם הִנֵּ֤ה בָאָה֙ וְ/נִֽהְיָ֔תָה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Cry and howl, son of man: for it shall be upon my people, it shall be upon all the princes of Israel: terrors by reason of the sword shall be upon my people: smite therefore upon thy thigh.", "web": "Cry and wail, son of man; for it is on my people, it is on all the princes of Israel: they are delivered over to the sword with my people; strike therefore on your thigh.", "bsb": "Cry out and wail, O son of man, for the sword is wielded against My people; it is against all the princes of Israel! They are tossed to the sword with My people; therefore strike your thigh.", "asv": "Cry and wail, son of man; for it is upon my people, it is upon all the princes of Israel: they are delivered over to the sword with my people; smite therefore upon thy thigh.", "ylt": "Cry and howl, son of man, For it hath been among My people, It is among all the princes of Israel, Cast unto the sword have been My people. Therefore strike on thy thigh,", "dra": "Cry, and howl, O son of man, for this sword is upon my people, it is upon all the princes of Israel, that are fled: they are delivered up to the sword with my people, strike therefore upon thy thigh,", "bbe": "Give loud cries and make sounds of grief, O son of man: for it has come on my people, it has come on all the rulers of Israel: fear of the sword has come on my people: for this cause give signs of grief.", "geneva": "Cry, and houle, sonne of man: for this shall come to my people, and it shall come vnto all the princes of Israel: the terrours of the sword shall be vpon my people: smite therefore vpon thy thigh.", "wycliffe": "Sone of man, crie thou, and yelle, for this swerd is maad in my puple, this in alle the duykis of Israel; thei that fledden ben youun to swerd with my puple. Therfor smite thou on thin hipe, for it is preuyd;", "rotherham": "Make an outcry and howl son of man, For the same hath come against my people, the same is against all the princes of Israel,- Who are thrown to the sword with my people, Therefore smite thou upon thy thigh.", "darby": "Cry and howl, son of man; for it shall be against my people, it shall be against all the princes of Israel: they are given up to the sword along with my people: smite therefore upon the thigh.", "twenty": "", "jps": "And it shall be, when they say unto thee: Wherefore sighest thou? that thou shalt say: Because of the tidings, for it cometh; and every heart shall melt, and all hands shall be slack, and every spirit shall be faint, and all knees shall drip with water; behold, it cometh, and it shall be done, saith the L-rd GOD.'", "acv": "Cry and wail, son of man, for it is upon my people. It is upon all the rulers of Israel. They are delivered over to the sword with my people. Smite therefore upon thy thigh.", "anderson": "", "haweis": "", "noyes": "Cry and howl, son of man! for it cometh upon my people, upon all the princes of Israel. They are given up to the sword with my people. Therefore smite upon thy thigh.", "webster": "Cry and howl, son of man: for it shall be upon my people, it [shall be] upon all the princes of Israel: terrors by reason of the sword shall be upon my people: smite therefore upon [thy] thigh.", "vulgate": "clama et ulula fili hominis quia hic factus est in populo meo hic in cunctis ducibus Israhel qui fugerant gladio traditi sunt cum populo meo idcirco plaude super femur;", "brenton": "Cry out and howl, son of man: for this sword is come upon my people, this sword is come upon all the princes of Israel: they shall be as strangers: judgment with the sword is come upon my people: therefore clap thine hands, for sentence has been passed:"}}, {"v": 13, "ref": "21:13", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Because it is a trial, and what if the sword contemn even the rod? it shall be no more, saith the Lord God.", "web": "For there is a trial; and what if even the rod that condemns shall be no more? says the Lord Yahweh.", "bsb": "Surely testing will come! And what if even the scepter, which the sword despises, does not continue?’ declares the Lord GOD.", "asv": "For there is a trial; and what if even the rod that contemneth shall be no more? saith the Lord Jehovah.", "ylt": "Because it is a trier, And what if even the sceptre it is despising? It shall not be, an affirmation of the Lord Jehovah.", "dra": "Because it is tried: and that when it shall overthrow the sceptre, and it shall not be, saith the Lord God.", "bbe": "...", "geneva": "For it is a triall, and what shall this be, if the sworde contemne euen the rodde? It shall be no more, saith the Lord God.", "wycliffe": "and this whanne it hath distried the ceptre, and it schal not be, seith the Lord God.", "rotherham": "For trial hath been made, What then, even though the royal rod despiseth, shall it not be? Demandeth My Lord. Yahweh.", "darby": "For the trial [is made]; and what if even the contemning sceptre shall be no [more]? saith the Lord Jehovah.", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "For there is a trial, and what if even the rod that scorns shall be no more? says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "The trial is made. And what if even the contemning staff should be no more? saith the Lord Jehovah.", "webster": "Because [it is] a trial, and what if [the sword] contemneth even the rod? it shall be no [more], saith the Lord GOD.", "vulgate": "quia probatus est et hoc cum sceptrum subverterit et non erit dicit Dominus Deus;", "brenton": "and what if even the tribe be rejected? it shall not be, saith the Lord God."}}, {"v": 14, "ref": "21:14", "o": "בֶּן אָדָ֕ם הִנָּבֵא֙ וְ/אָ֣מַרְתָּ֔ כֹּ֖ה אָמַ֣ר אֲדֹנָ֑/י אֱמֹ֕ר חֶ֥רֶב חֶ֛רֶב הוּחַ֖דָּה וְ/גַם מְרוּטָֽה", "en": {"kjv": "Thou therefore, son of man, prophesy, and smite thine hands together, and let the sword be doubled the third time, the sword of the slain: it is the sword of the great men that are slain, which entereth into their privy chambers.", "web": "You therefore, son of man, prophesy, and strike your hands together; and let the sword be doubled the third time, the sword of the deadly wounded: it is the sword of the great one who is deadly wounded, which enters into their rooms.", "bsb": "‘So then, son of man, prophesy and strike your hands together. Let the sword strike two times, even three. It is a sword that slays, a sword of great slaughter closing in on every side!", "asv": "Thou therefore, son of man, prophesy, and smite thy hands together; and let the sword be doubled the third time, the sword of the deadly wounded: it is the sword of the great one that is deadly wounded, which entereth into their chambers.", "ylt": "And thou, son of man, prophesy, And smite hand on hand, And bent is the sword a third time, The sword of the wounded! It is the sword of the wounded--the great one, That is entering the inner chamber to them.", "dra": "Thou therefore, O son of man, prophesy, and strike thy hands together, and let the sword be doubled, and let the sword of the slain be tripled: this is the sword of a great slaughter, that maketh them stand amazed,", "bbe": "So then, son of man, be a prophet, and put your hands together with a loud sound, and give two blows with the sword, and even three; it is the sword of those who are wounded, even the sword of the wounded; the great sword which goes round about them.", "geneva": "Thou therefore, sonne of man, prophecie, and smite hand to hand, and let the sworde be doubled: let the sworde that hath killed, returne the third time: it is the sword of the great slaughter entring into their priuie chambers.", "wycliffe": "Therfor, sone of man, profesie thou, and smyte thou hond to hond, and the swerd be doublid, and the swerd of sleeris be treblid; this is the swerd of greet sleyng, that schal make hem astonyed,", "rotherham": "Thou, therefore, son of man, Prophesy, and smite thy hands together, And let the sword smite twice thrice the sword of the slain! the same is the great sword of the slain, that which hemmeth them in.", "darby": "And thou, son of man, prophesy, and smite thy hands together; for [the strokes of] the sword shall be doubled the third time: it is the sword of the slain, the sword that hath slain the great one, which encompasseth them privily.", "twenty": "", "jps": "'Son of man, prophesy, and say: Thus saith HaShem: Say: A sword, a sword, it is sharpened, and also furbished:", "acv": "Thou therefore, son of man, prophesy, and smite thy hands together. And let the sword be doubled the third time, the sword of the deadly wounded. It is the sword of the great man who is deadly wounded, which enters into their chambers.", "anderson": "", "haweis": "", "noyes": "Thou, therefore, son of man, prophesy, and smite thine hands together! for twice, yea thrice, cometh the sword, a sword of slaughter, a sword of great slaughter, that besetteth them on every side.", "webster": "Thou therefore, son of man, prophesy, and smite [thy] hands together, and let the sword be doubled the third time, the sword of the slain: it [is] the sword of the great [men that are] slain, which entereth into their private chambers.", "vulgate": "tu ergo fili hominis propheta et percute manu ad manum et duplicetur gladius ac triplicetur gladius interfectorum hic est gladius occisionis magnae qui obstupescere eos facit;", "brenton": "And thou, son of man, prophesy, and clap thine hands, and take a second sword: the third sword is the sword of the slain, the great sword of the slain: and thou shalt strike them with amazement, lest the heart should faint"}}, {"v": 15, "ref": "21:15", "o": "לְמַ֨עַן טְבֹ֤חַ טֶ֨בַח֙ הוּחַ֔דָּה לְמַעַן הֱיֵה לָ֥/הּ בָּ֖רָק מֹרָ֑טָּה א֣וֹ נָשִׂ֔ישׂ שֵׁ֥בֶט בְּנִ֖/י מֹאֶ֥סֶת כָּל עֵֽץ", "en": {"kjv": "I have set the point of the sword against all their gates, that their heart may faint, and their ruins be multiplied: ah! it is made bright, it is wrapped up for the slaughter.", "web": "I have set the threatening sword against all their gates, that their heart may melt, and their stumblings be multiplied: ah! it is made as lightning, it is pointed for slaughter.", "bsb": "So that their hearts may melt and many may stumble, I have appointed at all their gates a sword for slaughter. Yes, it is ready to flash like lightning; it is drawn for slaughter.", "asv": "I have set the threatening sword against all their gates, that their heart may melt, and their stumblings be multiplied: ah! it is made as lightning, it is pointed for slaughter.", "ylt": "To melt the heart, and to multiply the ruins, By all their gates I have set the point of a sword. Ah, it is made for brightness, Wrapped up for slaughter.", "dra": "And languish in heart, and that multiplieth ruins. In all their gates I have set the dread of the sharp sword, the sword that is furbished to glitter, that is made ready for slaughter.", "bbe": "In order that hearts may become soft, and the number of those who are falling may be increased, I have sent death by the sword against all their doors: you are made like a flame, you are polished for death.", "geneva": "I haue brought the feare of the sword into all their gates to make their heart to faint, and to multiplie their ruines. Ah it is made bright, and it is dressed for the slaughter.", "wycliffe": "and to faile in herte, and multiplieth fallingis. In alle the yatis of hem Y yaf disturbling of a swerd, scharp and maad briyt to schyne, gird to sleynge.", "rotherham": "That the heart may melt And the overthrow be multiplied at all their gates, I have recompensed a slaying by the sword: Surely it hath been made ready to flash like lightning, keen for slaughter.", "darby": "In order that the heart may melt, and the stumbling-blocks be multiplied, I have set the threatening sword against all their gates: ah! it is made glittering, it is whetted for the slaughter.", "twenty": "", "jps": "It is sharpened that it may make a sore slaughter, it is furbished that it may glitter--or shall we make mirth? --against the rod of My son, contemning every tree.", "acv": "I have set the threatening sword against all their gates, that their heart may melt, and their stumblings be multiplied. Ah! It is made as lightning. It is pointed for slaughter.", "anderson": "", "haweis": "", "noyes": "That their hearts may faint, and their overthrown may be multiplied, I have set the terror of the sword against all their gates. Ah, how is it made to glitter, polished for slaughter!", "webster": "I have set the point of the sword against all their gates, that [their] heart may faint, and [their] ruins be multiplied: ah! [it is] made bright, [it is] sharpened for the slaughter.", "vulgate": "et corde tabescere et multiplicat ruinas in omnibus portis eorum dedi conturbationem gladii acuti et limati ad fulgendum amicti ad caedem;", "brenton": "and the weak ones be multiplied at every gate—they are given up to the slaughter of the sword: it is well fitted for slaughter, it is well fitted for glittering."}}, {"v": 16, "ref": "21:16", "o": "וַ/יִּתֵּ֥ן אֹתָ֛/הּ לְ/מָרְטָ֖ה לִ/תְפֹּ֣שׂ בַּ/כָּ֑ף הִֽיא הוּחַ֤דָּה חֶ֨רֶב֙ וְ/הִ֣יא מֹרָ֔טָּה לָ/תֵ֥ת אוֹתָ֖/הּ בְּ/יַד הוֹרֵֽג", "en": {"kjv": "Go thee one way or other, either on the right hand, or on the left, whithersoever thy face is set.", "web": "Gather yourselves together, go to the right, set yourselves in array, go to the left, wherever your face is set.", "bsb": "Slash to the right; set your blade to the left— wherever your blade is directed.", "asv": "Gather thee together, go to the right, set thyself in array, go to the left, whithersoever thy face is set.", "ylt": "Take possession of the right, place thyself at the left, Whither thy face is appointed.", "dra": "Be thou sharpened, go to the right hand, or to the left, which way soever thou hast a mind to set thy face.", "bbe": "Be pointed to the right, to the left, wherever your edge is ordered.", "geneva": "Get thee alone: goe to the right hande, or get thy selfe to the left hande, whithersoeuer thy face turneth.", "wycliffe": "Be thou maad scharp, go thou to the riyt side, ether to the left side, whidur euer the desir of thi face is.", "rotherham": "One firm stroke to the right. Turn to the left,- Whithersoever thine edge is directed,", "darby": "Gather up [strength], go to the right hand, turn thee, go to the left, whithersoever thy face is appointed.", "twenty": "", "jps": "And it is given to be furbished, that it may be handled; the sword, it is sharpened, yea, it is furbished, to give it into the hand of the slayer.", "acv": "Gather thee together. Go to the right. Set thyself in array. Go to the left, wherever thy face is set.", "anderson": "", "haweis": "", "noyes": "Unite thyself, smite to the right, prepare thyself, smite to the left, whithersoever thine edge is turned!", "webster": "Go thee one way or other, [either] on the right hand, [or] on the left, whithersoever thy face [is] set.", "vulgate": "exacuere vade ad dextram sive ad sinistram quocumque faciei tuae est appetitus;", "brenton": "And do thou go on, sharpen thyself on the right and on the left whithersoever thy face may set itself."}}, {"v": 17, "ref": "21:17", "o": "זְעַ֤ק וְ/הֵילֵל֙ בֶּן אָדָ֔ם כִּי הִיא֙ הָיתָ֣ה בְ/עַמִּ֔/י הִ֖יא בְּ/כָל נְשִׂיאֵ֣י יִשְׂרָאֵ֑ל מְגוּרֵ֤י אֶל חֶ֨רֶב֙ הָי֣וּ אֶת עַמִּ֔/י לָ/כֵ֖ן סְפֹ֥ק אֶל יָרֵֽךְ", "en": {"kjv": "I will also smite mine hands together, and I will cause my fury to rest: I the Lord have said it.", "web": "I will also strike my hands together, and I will cause my wrath to rest: I, Yahweh, have spoken it.", "bsb": "I too will strike My hands together, and I will satisfy My wrath.’ I, the LORD, have spoken.”", "asv": "I will also smite my hands together, and I will cause my wrath to rest: I, Jehovah, have spoken it.", "ylt": "And I also, I smite My hand on my hand, And have caused My fury to rest; I, Jehovah, have spoken.'", "dra": "And I will clap my hands together, and will satisfy my indignation: I the Lord have spoken.", "bbe": "And I will put my hands together with a loud sound, and I will let my wrath have rest: I the Lord have said it.", "geneva": "I wil also smite mine hands together, and wil cause my wrath to cease. I the Lord haue said it.", "wycliffe": "Certis and Y schal smyte with hond to hond, and Y schal fille myn indignacioun; Y the Lord spak.", "rotherham": "Yea even I myself, will smite my hands together, And will cause mine indignation to find rest,— I Yahweh, have spoken.", "darby": "And I myself will smite my hands together, and I will satisfy my fury: I Jehovah have spoken [it].", "twenty": "", "jps": "Cry and wail, son of man; for it is upon My people, it is upon all the princes of Israel; they are thrust down to the sword with My people; smite therefore upon thy thigh.", "acv": "I will also smite my hands together, and I will cause my wrath to rest. I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "I also will smite my hands together, and cause mine anger to cease. I, Jehovah, have spoken it.", "webster": "I will also smite my hands together, and I will cause my fury to rest: I the LORD have said [it].", "vulgate": "quin et ego plaudam manu ad manum et implebo indignationem meam ego Dominus locutus sum;", "brenton": "And I also will clap my hands, and let loose my fury: I the Lord have spoken it."}}, {"v": 18, "ref": "21:18", "o": "כִּ֣י בֹ֔חַן וּ/מָ֕ה אִם גַּם שֵׁ֥בֶט מֹאֶ֖סֶת לֹ֣א יִֽהְיֶ֑ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "The word of the Lord came unto me again, saying,", "web": "Yahweh’s word came to me again, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "The word of Jehovah came unto me again, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me again, saying,", "geneva": "The worde of the Lord came vnto mee againe, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "Then came the word of Yahweh unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "For there is a trial; and what if it contemn even the rod? It shall be no more, saith the L-rd GOD.", "acv": "The word of Jehovah came to me again, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came to me again, saying:", "webster": "The word of the LORD came to me again, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 19, "ref": "21:19", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם הִנָּבֵ֕א וְ/הַ֖ךְ כַּ֣ף אֶל כָּ֑ף וְ/תִכָּפֵ֞ל חֶ֤רֶב שְׁלִישִׁ֨תָ/ה֙ חֶ֣רֶב חֲלָלִ֔ים הִ֗יא חֶ֚רֶב חָלָ֣ל הַ/גָּד֔וֹל הַ/חֹדֶ֖רֶת לָ/הֶֽם", "en": {"kjv": "Also, thou son of man, appoint thee two ways, that the sword of the king of Babylon may come: both twain shall come forth out of one land: and choose thou a place, choose it at the head of the way to the city.", "web": "Also, you son of man, appoint two ways, that the sword of the king of Babylon may come; they both shall come out of one land: and mark out a place, mark it out at the head of the way to the city.", "bsb": "“Now you, son of man, mark out two roads for the sword of the king of Babylon to take, both starting from the same land. And make a signpost where the road branches off to each city.", "asv": "Also, thou son of man, appoint thee two ways, that the sword of the king of Babylon may come; they twain shall come forth out of one land: and mark out a place, mark it out at the head of the way to the city.", "ylt": "`And thou, son of man, appoint for thee two ways, for the coming in of the sword of the king of Babylon; from one land they come forth, both of them, and a station prepare thou, at the top of the way of the city prepare it .", "dra": "And thou son of man, set thee two ways, for the sword of the king of Babylon to come: both shall come forth out of one land: and with his hand he shall draw lots, he shall consult at the head of the way of the city.", "bbe": "And you, son of man, have two ways marked out, so that the sword of the king of Babylon may come; let the two of them come out of one land: and let there be a pillar at the top of the road:", "geneva": "Also thou sonne of man, appoint thee two wayes, that the sworde of the King of Babel may come: both twaine shall come out of one lande, and chuse a place, and chuse it in the corner of the way of the citie.", "wycliffe": "and he seide, And thou, sone of man, sette to thee twei weies, that the swerd of the king of Babiloyne come; bothe schulen go out of o lond, and bi the hond he schal take coniecting; he schal coniecte in the heed of the weie of the citee,", "rotherham": "Thou, therefore son of man. Appoint thee two ways For the sword of the king of Babylon to enter, Out of one land shall those two ways come,— And a hand, engrave thou, At the head of the way to the city, engrave it.;", "darby": "And thou, son of man, set thee two ways, by which the sword of the king of Babylon may come — out of one land shall they both come — and make thee a signpost, make it at the head of the way to the city.", "twenty": "", "jps": "Thou therefore, son of man, prophesy, and smite thy hands together; and let the sword be doubled the third time, the sword of those to be slain; it is the sword of the great one that is to be slain, which compasseth them about.", "acv": "Also, thou son of man, appoint thee two ways that the sword of the king of Babylon may come. Those two shall come forth out of one land. And mark out a place. Mark it out at the head of the way to the city.", "anderson": "", "haweis": "", "noyes": "Do thou, son of man, appoint thee two ways by which the sword of the king of Babylon may come; from one land shall both of them come; and choose thou a place, choose it at the head of the way to the city.", "webster": "Also, thou son of man, appoint thee two ways, that the sword of the king of Babylon may come: both [ways] shall come forth from one land: and choose thou a place, choose [it] at the head of the way to the city.", "vulgate": "et tu fili hominis pone tibi duas vias ut veniat gladius regis Babylonis de terra una egredientur ambo et manu capiet coniecturam in capite viae civitatis coniciet;", "brenton": "and thou, son of man, appoint thee two ways, that the sword of the king of Babylon may enter in: the two shall go forth of one country; and there shall be a force at the top of the way of the city, thou shalt set it at the top of the way,"}}, {"v": 20, "ref": "21:20", "o": "לְמַ֣עַן לָ/מ֣וּג לֵ֗ב וְ/הַרְבֵּה֙ הַ/מִּכְשֹׁלִ֔ים עַ֚ל כָּל שַׁ֣עֲרֵי/הֶ֔ם נָתַ֖תִּי אִבְחַת חָ֑רֶב אָ֛ח עֲשׂוּיָ֥ה לְ/בָרָ֖ק מְעֻטָּ֥ה לְ/טָֽבַח", "en": {"kjv": "Appoint a way, that the sword may come to Rabbath of the Ammonites, and to Judah in Jerusalem the defenced.", "web": "You shall appoint a way for the sword to come to Rabbah of the children of Ammon, and to Judah in Jerusalem the fortified.", "bsb": "Mark out one road for the sword to come against Rabbah of the Ammonites, and another against Judah into fortified Jerusalem.", "asv": "Thou shalt appoint a way for the sword to come to Rabbah of the children of Ammon, and to Judah in Jerusalem the fortified.", "ylt": "A way appoint for the coming of the sword, Unto Rabbath of the sons of Ammon, And to Judah, in Jerusalem--the fenced.", "dra": "Thou shalt make a way that the sword may come to Rabbath of the children of Ammon, and to Juda unto Jerusalem the strong city.", "bbe": "Put a pillar at the top of the road for the sword to come to Rabbah in the land of the children of Ammon, and to Judah and to Jerusalem in the middle of her.", "geneva": "Appoint a way, that the sworde may come to Rabbath of the Ammonites, and to Iudah in Ierusalem the strong citie.", "wycliffe": "settinge a weye, that the swerd come to Rabath of the sones of Amon, and to Juda in to Jerusalem moost strong.", "rotherham": "A way, shalt thou appoint, for the sword to enter. Even to Rabbah of the sons of Ammon,— And to Judah against Jerusalem, the defenced,", "darby": "Appoint a way for the coming of the sword to Rabbah of the children of Ammon, and to Judah at the fenced [city] of Jerusalem.", "twenty": "", "jps": "I have set the point of the sword against all their gates, that their heart may melt, and their stumblings be multiplied; ah! it is made glittering, it is sharpened for slaughter.", "acv": "Thou shall appoint a way for the sword to come to Rabbah of the sons of Ammon, and to Judah in Jerusalem the fortified.", "anderson": "", "haweis": "", "noyes": "Appoint a way, that the sword may come towards Rabbath of the sons of Ammon, and towards Judah, to Jerusalem, the fenced city.", "webster": "Appoint a way, that the sword may come to Rabbah of the Ammonites, and to Judah in Jerusalem the fortified.", "vulgate": "viam pones ut veniat gladius ad Rabbath filiorum Ammon et ad Iudam in Hierusalem munitissimam;", "brenton": "that the sword may enter in upon Rabbath of the children of Ammon, and upon Judea, and upon Jerusalem in the midst thereof."}}, {"v": 21, "ref": "21:21", "o": "הִתְאַחֲדִ֥י הֵימִ֖נִי הָשִׂ֣ימִי הַשְׂמִ֑ילִי אָ֖נָה פָּנַ֥יִ/ךְ מֻעָדֽוֹת", "en": {"kjv": "For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination: he made his arrows bright, he consulted with images, he looked in the liver.", "web": "For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination: he shook the arrows back and forth, he consulted the teraphim, he looked in the liver.", "bsb": "For the king of Babylon stands at the fork in the road, at the junction of the two roads, to seek an omen: He shakes the arrows, he consults the idols, he examines the liver.", "asv": "For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination: he shook the arrows to and fro, he consulted the teraphim, he looked in the liver.", "ylt": "For stood hath the king of Babylon at the head of the way, At the top of the two ways, to use divination, He hath moved lightly with the arrows, He hath asked at the teraphim, He hath looked on the liver.", "dra": "For the king of Babylon stood in the highway, at the head of two ways, seeking divination, shuffling arrows: he inquired of the idols, and consulted entrails.", "bbe": "For the king of Babylon took his place at the parting of the ways, at the top of the two roads, to make use of secret arts: shaking the arrows this way and that, he put questions to the images of his gods, he took note of the inner parts of dead beasts.", "geneva": "And the King of Babel stoode at the parting of the way, at the head of the two wayes, consulting by diuination, and made his arrowes bright: hee consulted with idoles, and looked in the liuer.", "wycliffe": "For the king of Babiloyne stood in the meeting of twey weies, in the heed of twei weies, and souyte dyuynyng, and medlide arowis; he axide idols, and took councel at entrails.", "rotherham": "For the king of Babylon, hath come to a stand, At the parting of the way At the head of the two ways To divine a divination:He hath shaken with arrows He hath asked of the household gods, He hath inspected the liver.", "darby": "For the king of Babylon standeth at the parting of the way, at the head of the two ways, to use divination: he shaketh [his] arrows, he inquireth of the teraphim, he looketh in the liver.", "twenty": "", "jps": "Go thee one way to the right, or direct thyself to the left; whither is thy face set?", "acv": "For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination. He shook the arrows to and fro. He consulted the teraphim. He looked in the liver.", "anderson": "", "haweis": "", "noyes": "For the king of Babylon shall stand at the parting of the way, at the head of the two ways, to use divination; he shall shake together his arrows, he shall consult the teraphim, he shall look at the liver.", "webster": "For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination; he made [his] arrows bright, he consulted with images, he looked in the liver.", "vulgate": "stetit enim rex Babylonis in bivio in capite duarum viarum divinationem quaerens commiscens sagittas interrogavit idola exta consuluit;", "brenton": "For the king of Babylon shall stand on the old way, at the head of the two ways, to use divination, to make bright the arrow, and to enquire of the graven images, and to examine the victims."}}, {"v": 22, "ref": "21:22", "o": "וְ/גַם אֲנִ֗י אַכֶּ֤ה כַפִּ/י֙ אֶל כַּפִּ֔/י וַ/הֲנִחֹתִ֖י חֲמָתִ֑/י אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "At his right hand was the divination for Jerusalem, to appoint captains, to open the mouth in the slaughter, to lift up the voice with shouting, to appoint battering rams against the gates, to cast a mount, and to build a fort.", "web": "In his right hand was the lot for Jerusalem, to set battering rams, to open the mouth in the slaughter, to lift up the voice with shouting, to set battering rams against the gates, to cast up mounds, to build forts.", "bsb": "In his right hand appears the portent for Jerusalem, where he is to set up battering rams, to call for the slaughter, to lift a battle cry, to direct the battering rams against the gates, to build a ramp, and to erect a siege wall.", "asv": "In his right hand was the divination for Jerusalem, to set battering rams, to open the mouth in the slaughter, to lift up the voice with shouting, to set battering rams against the gates, to cast up mounds, to build forts.", "ylt": "At his right hath been the divination--Jerusalem, To place battering-rams, To open the mouth with slaughter, To lift up a voice with shouting, To place battering-rams against the gates, To pour out a mount, to build a fortification.", "dra": "On his right hand was the divination for Jerusalem, to set battering rams, to open the mouth in slaughter, to lift up the voice in howling, to set engines against the gates, to cast up a mount, to build forts.", "bbe": "At his right hand was the fate of Jerusalem, to give orders for destruction, to send up the war-cry, to put engines of war against the doors, lifting up earthworks, building walls.", "geneva": "At his right hand was the diuination for Ierusalem to appoint captaines, to open their mouth in the slaughter, and to lift vp their voyce with shouting, to laye engines of warre against the gates, to cast a mount, and to builde a fortresse.", "wycliffe": "Dyuynyng was maad to his riyt side on Jerusalem, that he sette engyns, that he opene mouth in sleyng, that he reise vois in yelling, that he sette engyns ayens the yatis, that he bere togidere erthe, that he bilde strengthinges.", "rotherham": "On his right hand, hath come the divination—Jerusalem! To plant battering-rams To open a hole by breach To lift up the voice with a war-shout,— To plant battering-rams against the gates, To cast up an earth-work To build a siege-wall.", "darby": "In his right hand is the lot of Jerusalem to appoint battering-rams, to open the mouth for bloodshed, to lift up the voice with shouting, to appoint battering-rams against the gates, to cast mounds, to build siege-towers.", "twenty": "", "jps": "I will also smite My hands together, and I will satisfy My fury; I HaShem have spoken it.'", "acv": "In his right hand was the divination for Jerusalem, to set battering rams, to open the mouth in the slaughter, to lift up the voice with shouting, to set battering rams against the gates, to cast up mounds, to build forts.", "anderson": "", "haweis": "", "noyes": "In his right hand shall be the lot: Jerusalem, to set battering-rams, to open the mouth with the war-cry, to lift up the voice in shouting, to set battering-rams against the gates, to cast up a mound, to build a tower.", "webster": "At his right hand was the divination for Jerusalem, to appoint captains, to open the mouth in the slaughter, to lift up the voice with shouting, to appoint [battering] rams against the gates, to cast a mount, [and] to build a fort.", "vulgate": "ad dextram eius facta est divinatio super Hierusalem ut ponat arietes ut aperiat os in caede ut elevet vocem in ululatu ut ponat arietes contra portas ut conportet aggerem ut aedificet munitiones;", "brenton": "On his right was the divination against Jerusalem, to cast a mound, to open the mouth in shouting, to lift up the voice with crying, to cast a mound against her gates, to cast up a heap, and to build forts."}}, {"v": 23, "ref": "21:23", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it shall be unto them as a false divination in their sight, to them that have sworn oaths: but he will call to remembrance the iniquity, that they may be taken.", "web": "It shall be to them as a false divination in their sight, who have sworn oaths to them; but he brings iniquity to memory, that they may be taken.", "bsb": "It will seem like a false omen to the eyes of those who have sworn allegiance to him, but it will draw attention to their guilt and take them captive.", "asv": "And it shall be unto them as a false divination in their sight, who have sworn oaths unto them; but he bringeth iniquity to remembrance, that they may be taken.", "ylt": "And it hath been to them as a false divination in their eyes, Who have sworn oaths to them, And he is causing iniquity to be remembered to be caught.", "dra": "And he shall be in their eyes as one consulting the oracle in vain, and imitating the leisure of sabbaths: but he will call to remembrance the iniquity that they may be taken.", "bbe": "And this answer given by secret arts will seem false to those who have given their oaths and have let them be broken: but he will keep the memory of evil-doing so that they may be taken.", "geneva": "And it shalbe vnto them as a false diuination in their sight for the othes made vnto them: but hee will call to remembrance their iniquitie, to the intent they should be taken.", "wycliffe": "And he shal be as counceling in veyn goddis answer bifor the iyen of hem, and seruynge the reste of sabatis; but he schal haue mynde on wickidnesse, to take.", "rotherham": "Though it will become to them a veritably false divination in their eyes, even when bound by oaths to them Yet, he, calling to mind iniquity, [will determine] that it shall be captured.", "darby": "And this shall be a false divination in their sight, for them that have sworn oaths; but he will call to remembrance the iniquity, that they may be taken.", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And it shall be to them as a false divination in their sight, who have sworn oaths to them. But he brings iniquity to remembrance, that they may be taken.", "anderson": "", "haweis": "", "noyes": "And this shall appear a false divination in their sight, because they swore oaths to them. But he shall call to remembrance their iniquity, that they may be taken.", "webster": "And it shall be to them as a false divination in their sight, to them that have sworn oaths: but he will call to remembrance the iniquity, that they may be taken.", "vulgate": "eritque quasi consulens frustra oraculum in oculis eorum et sabbatorum otium imitans ipse autem recordabitur iniquitatis ad capiendum;", "brenton": "And he was to them as one using divination before them, and he himself recounting his iniquities, that they might be borne in mind."}}, {"v": 24, "ref": "21:24", "o": "וְ/אַתָּ֨ה בֶן אָדָ֜ם שִׂים לְ/ךָ֣ שְׁנַ֣יִם דְּרָכִ֗ים לָ/בוֹא֙ חֶ֣רֶב מֶֽלֶךְ בָּבֶ֔ל מֵ/אֶ֥רֶץ אֶחָ֖ד יֵצְא֣וּ שְׁנֵי/הֶ֑ם וְ/יָ֣ד בָּרֵ֔א בְּ/רֹ֥אשׁ דֶּֽרֶךְ עִ֖יר בָּרֵֽא", "en": {"kjv": "Therefore thus saith the Lord God; Because ye have made your iniquity to be remembered, in that your transgressions are discovered, so that in all your doings your sins do appear; because, I say, that ye are come to remembrance, ye shall be taken with the hand.", "web": "Therefore thus says the Lord Yahweh: Because you have made your iniquity to be remembered, in that your transgressions are uncovered, so that in all your doings your sins appear; because you have come to memory, you shall be taken with the hand.", "bsb": "Therefore this is what the Lord GOD says: ‘Because you have drawn attention to your guilt, exposing your transgressions, so that your sins are revealed in all your deeds—because you have come to remembrance—you shall be taken in hand.", "asv": "Therefore thus saith the Lord Jehovah: Because ye have made your iniquity to be remembered, in that your transgressions are uncovered, so that in all your doings your sins do appear; because that ye are come to remembrance, ye shall be taken with the hand.", "ylt": "Therefore, thus said the Lord Jehovah: Because of your causing your iniquity to be remembered, In your transgressions being revealed, For your sins being seen, in all your doings, Because of your being remembered, By the hand ye are caught.", "dra": "Therefore thus saith the Lord God: Because you have remembered your iniquity, and have discovered your prevarications, and your sins have appeared in all your devices: because, I say, You have remembered, you shall be taken with the hand.", "bbe": "For this cause the Lord has said: Because you have made your evil-doing come to mind by the uncovering of your wrongdoing, causing your sins to be seen in all your evil-doings; because you have come to mind, you will be taken in them.", "geneva": "Therefore thus sayeth the Lord God, Because ye haue made your iniquitie to bee remembred, in discouering your rebellion, that in al your workes your sinnes might appeare: because, I say, that ye are come to remembrance, ye shall be taken with the hand.", "wycliffe": "Therfor the Lord God seith these thingis, For that that ye hadden mynde on youre wickidnesse, and schewiden youre trespassyngis, and youre synnes apperiden in alle youre thouytis, forsothe for that that ye hadden mynde, ye schulen be takun bi hond.", "rotherham": "Therefore Thus saith My Lord. Yahweh, Because ye have brought to mind your iniquity, by revealing your transgressions causing your sins to appear in all your doings,- Because ye have brought yourselves to mind By force shall ye be captured.", "darby": "Therefore thus saith the Lord Jehovah: Because ye make your iniquity to be remembered in that your transgressions are discovered, so that in all your doings your sins appear; because ye are come to remembrance, ye shall be taken with the hand.", "twenty": "", "jps": "'Now, thou son of man, make thee two ways, that the sword of the king of Babylon may come; they twain shall come forth out of one land; and mark a signpost, mark it clear at the head of the way to the city.", "acv": "Therefore thus says the lord Jehovah: Because ye have made your iniquity to be remembered, in that your transgressions are uncovered, so that in all your doings your sins do appear, because ye have come to remembrance, ye shall be taken with the hand.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because ye make your iniquity to be remembered, in that your transgressions are discovered, so that in all your doings your sins do appear,—because, I say, ye bring yourselves into remembrance, ye shall be taken with that hand.", "webster": "Therefore thus saith the Lord GOD; Because ye have made your iniquity to be remembered, in that your transgressions are disclosed, so that in all your doings your sins do appear; because, [I say], that ye are come to remembrance, ye shall be taken with the hand.", "vulgate": "idcirco haec dicit Dominus Deus pro eo quod recordati estis iniquitatis vestrae et revelastis praevaricationes vestras et apparuerunt peccata vestra in omnibus cogitationibus vestris pro eo inquam quod recordati estis manu capiemini;", "brenton": "Therefore thus saith the Lord, Because ye have caused your iniquities to be remembered, in the discovery of your wickedness, so that your sins should be seen, in all your wickedness and in your evil practices; because ye have caused remembrance of them, in these shall ye be taken."}}, {"v": 25, "ref": "21:25", "o": "דֶּ֣רֶךְ תָּשִׂ֔ים לָ/ב֣וֹא חֶ֔רֶב אֵ֖ת רַבַּ֣ת בְּנֵֽי עַמּ֑וֹן וְ/אֶת יְהוּדָ֥ה בִ/ירוּשָׁלִַ֖ם בְּצוּרָֽה", "en": {"kjv": "And thou, profane wicked prince of Israel, whose day is come, when iniquity shall have an end,", "web": "You, deadly wounded wicked one, the prince of Israel, whose day has come, in the time of the iniquity of the end,", "bsb": "And you, O profane and wicked prince of Israel, the day has come for your final punishment.’", "asv": "And thou, O deadly wounded wicked one, the prince of Israel, whose day is come, in the time of the iniquity of the end,", "ylt": "And thou, wounded, wicked one, Prince of Israel, whose day hath come, In the time of the iniquity of the end!", "dra": "But thou profane wicked prince of Israel, whose day is come that hath been appointed in the time of iniquity:", "bbe": "And you, O evil one, wounded to death, O ruler of Israel, whose day has come in the time of the last punishment;", "geneva": "And thou prince of Israel polluted, and wicked, whose day is come, when iniquitie shall haue an ende,", "wycliffe": "But thou, cursid wickid duyk of Israel, whos dai bifor determyned is comun in the tyme of wickidnesse,", "rotherham": "Thou therefore, O profane, lawless one, prince of Israel,- Whose day hath come, in a time of final iniquity:", "darby": "And thou, profane, wicked prince of Israel, whose day is come, at the time of the iniquity of the end,", "twenty": "", "jps": "Thou shalt make a way, that the sword may come to Rabbah of the children of Ammon, and to Judah in Jerusalem the fortified.", "acv": "And thou, O deadly wounded wicked man, the ruler of Israel, whose day has come, in the time of the iniquity of the end,", "anderson": "", "haweis": "", "noyes": "And thou, profane, wicked prince of Israel, whose day cometh in the time when iniquity bringeth destruction!", "webster": "And thou, profane wicked prince of Israel, whose day is come, when iniquity [shall have] an end,", "vulgate": "tu autem profane impie dux Israhel cuius venit dies in tempore iniquitatis praefinita;", "brenton": "And thou profane wicked prince of Israel, whose day, even an end, is come in a sea of iniquity, thus saith the Lord;"}}, {"v": 26, "ref": "21:26", "o": "כִּֽי עָמַ֨ד מֶלֶךְ בָּבֶ֜ל אֶל אֵ֣ם הַ/דֶּ֗רֶךְ בְּ/רֹ֛אשׁ שְׁנֵ֥י הַ/דְּרָכִ֖ים לִ/קְסָם קָ֑סֶם קִלְקַ֤ל בַּֽ/חִצִּים֙ שָׁאַ֣ל בַּ/תְּרָפִ֔ים רָאָ֖ה בַּ/כָּבֵֽד", "en": {"kjv": "Thus saith the Lord God; Remove the diadem, and take off the crown: this shall not be the same: exalt him that is low, and abase him that is high.", "web": "thus says the Lord Yahweh: Remove the turban, and take off the crown; this will not be as it was; exalt that which is low, and abase that which is high.", "bsb": "This is what the Lord GOD says: ‘Remove the turban, and take off the crown. Things will not remain as they are: Exalt the lowly and bring low the exalted.", "asv": "thus saith the Lord Jehovah: Remove the mitre, and take off the crown; this shall be no more the same; exalt that which is low, and abase that which is high.", "ylt": "Thus said the Lord Jehovah: Turn aside the mitre, and bear away the crown, This--not this--the low make high, And the high make low.", "dra": "Thus saith the Lord God: Remove the diadem, take off the crown: is it not this that hath exalted the low one, and brought down him that was high?", "bbe": "This is what the Lord has said: Take away the holy head-dress, take off the crown: this will not be again: let that which is low be lifted up, and that which is high be made low.", "geneva": "Thus saith the Lord God, I will take away the diademe, and take off the crowne: this shalbe no more the same: I wil exalt the humble, and will abase him that is hie.", "wycliffe": "the Lord God seith these thingis, Do awei the mitre, take awei the coroun; whether it is not this that reiside the meke man, and made low the hiy man?", "rotherham": "Thus, saith My Lord. Yahweh, Remove the turban, And lift off the crown,— This not that, The abased, exalt, And the exalted, abase.", "darby": "— thus saith the Lord Jehovah: Remove the mitre and take off the crown; what is shall be no [more]. Exalt that which is low, and abase that which is high.", "twenty": "", "jps": "For the king of Babylon standeth at the parting of the way, at the head of the two ways, to use divination; he shaketh the arrows to and fro, he inquireth of the teraphim, he looketh in the liver.", "acv": "thus says the lord Jehovah: Remove the miter, and take off the crown. This shall be no more the same. Exalt that which is low, and abase that which is high.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I will remove the diadem, and take away the crown! This shall no more be this. I exalt him that is low, and abase him that is high.", "webster": "Thus saith the Lord GOD; Remove the diadem, and take off the crown: this [shall] not [be] the same: exalt [him that is] low, and abase [him that is] high.", "vulgate": "haec dicit Dominus Deus aufer cidarim tolle coronam nonne haec est quae humilem sublevavit et sublimem humiliavit;", "brenton": "Thou hast taken off the mitre and put on the crown, it shall not have such another after it: thou hast abased that which was high, and exalted that which was low."}}, {"v": 27, "ref": "21:27", "o": "בִּֽ/ימִינ֞/וֹ הָיָ֣ה הַ/קֶּ֣סֶם יְרוּשָׁלִַ֗ם לָ/שׂ֤וּם כָּרִים֙ לִ/פְתֹּ֤חַ פֶּה֙ בְּ/רֶ֔צַח לְ/הָרִ֥ים ק֖וֹל בִּ/תְרוּעָ֑ה לָ/שׂ֤וּם כָּרִים֙ עַל שְׁעָרִ֔ים לִ/שְׁפֹּ֥ךְ סֹלְלָ֖ה לִ/בְנ֥וֹת דָּיֵֽק", "en": {"kjv": "I will overturn, overturn, overturn, it: and it shall be no more, until he come whose right it is; and I will give it him.", "web": "I will overturn, overturn, overturn it: this also shall be no more, until he come whose right it is; and I will give it.", "bsb": "A ruin, a ruin, I will make it a ruin! And it will not be restored until the arrival of Him to whom it belongs, to whom I have assigned the right of judgment.’", "asv": "I will overturn, overturn, overturn it: this also shall be no more, until he come whose right it is; and I will give it him.", "ylt": "An overturn, overturn, overturn, I make it, Also this hath not been till the coming of Him, Whose is the judgment, and I have given it.", "dra": "I will shew it to be iniquity, iniquity, iniquity: but this was not done till he came to whom judgment belongeth, and I will give it him.", "bbe": "I will let it be overturned, overturned, overturned: this will not be again till he comes whose right it is; and I will give it to him.", "geneva": "I wil ouerturne, ouerturne, ouerturne it, and it shall be no more vntill he come, whose right it is, and I will giue it him.", "wycliffe": "Wickidnesse, wickidnesse, wickidnesse Y schal putte it; and this schal not be doon til he come, whos the doom is, and Y schal bitake to hym.", "rotherham": "An overthrow overthrow overthrow, will I make it,— Even this, hath not befallen until the coming of One to whom belongeth the right Then will I bestow it.", "darby": "I will overturn, overturn, overturn it! This also shall be no [more], until he come whose right it is; and I will give it [to him].", "twenty": "", "jps": "In his right hand is the lot Jerusalem, to set battering rams, to open the mouth for the slaughter, to lift up the voice with shouting, to set battering rams against the gates, to cast up mounds, to build forts.", "acv": "I will overturn, overturn, overturn it. This also shall be no more, until he comes whose right it is. And I will give it.", "anderson": "", "haweis": "", "noyes": "I will destroy, destroy, destroy it; and it shall be no more until he come to whom the right belongeth, and to whom I will give it.", "webster": "I will overturn, overturn, overturn it: and it shall be no [more], until he cometh whose right it is; and I will give it [him].", "vulgate": "iniquitatem iniquitatem iniquitatem ponam eam et hoc nunc factum est donec veniret cuius est iudicium et tradam ei;", "brenton": "Injustice, injustice, injustice, will I make it: woe to it: such shall it be until he comes to whom it belongs; and I will deliver it to him."}}, {"v": 28, "ref": "21:28", "o": "וְ/הָיָ֨ה לָ/הֶ֤ם כ/קסום כִּ/קְסָם שָׁוְא֙ בְּ/עֵ֣ינֵי/הֶ֔ם שְׁבֻעֵ֥י שְׁבֻע֖וֹת לָ/הֶ֑ם וְ/הֽוּא מַזְכִּ֥יר עָוֺ֖ן לְ/הִתָּפֵֽשׂ", "en": {"kjv": "And thou, son of man, prophesy and say, Thus saith the Lord God concerning the Ammonites, and concerning their reproach; even say thou, The sword, the sword is drawn: for the slaughter it is furbished, to consume because of the glittering:", "web": "You, son of man, prophesy, and say, Thus says the Lord Yahweh concerning the children of Ammon, and concerning their reproach; and say, A sword, a sword is drawn, for the slaughter it is furbished, to cause it to devour, that it may be as lightning;", "bsb": "Now prophesy, son of man, and declare that this is what the Lord GOD says concerning the Ammonites and their contempt: ‘A sword! A sword is drawn for slaughter, polished to consume, to flash like lightning—", "asv": "And thou, son of man, prophesy, and say, Thus saith the Lord Jehovah concerning the children of Ammon, and concerning their reproach; and say thou, A sword, a sword is drawn, for the slaughter it is furbished, to cause it to devour, that it may be as lightning;", "ylt": "And thou, son of man, prophesy, and thou hast said: Thus said the Lord Jehovah concerning the sons of Ammon, and concerning their reproach: and thou hast said: A sword, a sword, open for slaughter, Polished to the utmost for brightness!", "dra": "And thou son of man, prophesy, and say: Thus saith the Lord God concerning the children of Ammon, and concerning their reproach, and thou shalt say: O sword, O sword, come out of the scabbard to kill, be furbished to destroy, and to glitter,", "bbe": "And you, son of man, say as a prophet, This is what the Lord has said about the children of Ammon and about their shame: Say, A sword, even a sword let loose, polished for death, to make it shining so that it may be like a flame:", "geneva": "And thou, sonne of man, prophecie, and say, Thus saith the Lord God to the children of Ammon, and to their blasphemie: say thou, I say, The sword, the sword is drawen foorth, and fourbished to the slaughter, to consume, because of the glittering:", "wycliffe": "And thou, sone of man, profesie, and seie, The Lord God seith these thingis to the sones of Amon, and to the schenschipe of hem; and thou schalt seie, A! thou swerd, A! thou swerd, drawun out to sle, maad briyte, that thou sle and schyne,", "rotherham": "Thou, therefore, son of man Prophesy and say, thus, saith My Lord. Yahweh, As to the sons of Ammon and as to their reproach Yea thou shalt say. A sword! a sword! Drawn for slaughter, Furbished, that when it beginneth, it may flash like lightning;", "darby": "And thou, son of man, prophesy and say, Thus speaketh the Lord Jehovah concerning the children of Ammon, and concerning their reproach; and thou shalt say, A sword, a sword is drawn; for the slaughter is it furbished, that it may consume, that it may glitter:", "twenty": "", "jps": "And it shall be unto them as a false divination in their sight, who have weeks upon weeks! but it bringeth iniquity to remembrance, that they may be taken.", "acv": "And thou, son of man, prophesy, and say, Thus says the lord Jehovah concerning the sons of Ammon, and concerning their reproach. And say thou, A sword, a sword is drawn. It is polished for the slaughter, to cause it to devour, that it may be as lightning,", "anderson": "", "haweis": "", "noyes": "And thou, son of man, prophesy, and say: Thus saith the Lord Jehovah concerning the sons of Ammon and their scorn; even say thou, The sword, the sword is drawn; to slay, to consume, is it furbished, so that it glittereth;", "webster": "And thou, son of man, prophesy and say, Thus saith the Lord GOD concerning the Ammonites, and concerning their reproach; even say thou, The sword, the sword [is] drawn: for the slaughter [it is] furbished, to consume because of the glittering:", "vulgate": "et tu fili hominis propheta et dic haec dicit Dominus Deus ad filios Ammon et ad obprobrium eorum et dices mucro mucro evaginate ad occidendum limate ut interficias et fulgeas;", "brenton": "And thou, son of man, prophesy, and thou shalt say, Thus saith the Lord, concerning the children of Ammon, and concerning their reproach; and thou shalt say, O sword, sword, drawn for slaughter, and drawn for destruction, awake, that thou mayest gleam."}}, {"v": 29, "ref": "21:29", "o": "לָ/כֵ֗ן כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ יַ֗עַן הַזְכַּרְ/כֶם֙ עֲוֺ֣נְ/כֶ֔ם בְּ/הִגָּל֣וֹת פִּשְׁעֵי/כֶ֗ם לְ/הֵֽרָאוֹת֙ חַטֹּ֣אותֵי/כֶ֔ם בְּ/כֹ֖ל עֲלִילֽוֹתֵי/כֶ֑ם יַ֚עַן הִזָּ֣כֶרְ/כֶ֔ם בַּ/כַּ֖ף תִּתָּפֵֽשׂוּ", "en": {"kjv": "Whiles they see vanity unto thee, whiles they divine a lie unto thee, to bring thee upon the necks of them that are slain, of the wicked, whose day is come, when their iniquity shall have an end.", "web": "while they see for you false visions, while they divine lies to you, to lay you on the necks of the wicked who are deadly wounded, whose day has come in the time of the iniquity of the end.", "bsb": "while they offer false visions for you and lying divinations about you— to be placed on the necks of the wicked who are slain, whose day has come, the time of their final punishment.", "asv": "while they see for thee false visions, while they divine lies unto thee, to lay thee upon the necks of the wicked that are deadly wounded, whose day is come in the time of the iniquity of the end.", "ylt": "In the seeing for thee of a vain thing, In the divining for thee of a lie, To put thee on the necks of the wounded of the wicked, whose day hath come, In the time of the iniquity of the end.", "dra": "Whilst they see vain things in thy regard, and they divine lies: to bring thee upon the necks of the wicked that are wounded, whose appointed day is come in the time of iniquity.", "bbe": "Your vision is to no purpose, your use of secret arts gives a false answer, to put it on the necks of evil-doers who are wounded to death, whose day has come, in the time of the last punishment.", "geneva": "Whiles they see vanitie vnto thee, and prophecied a lie vnto thee to bring thee vpon the neckes of the wicked that are slaine, whose day is come when their iniquitie shall haue an ende.", "wycliffe": "whanne veyn thingis weren seien to thee, and leesingis weren dyuynyd, that thou schuldist be youun on the neckis of wickid men woundid, the dai of whiche bifore determyned schal come in the tyme of wickidnesse, turne thou ayen in to thi schethe,", "rotherham": "Since they see for thee, false visions, Since they divine for thee lies, To stretch thee upon the necks of them who are the most profaned of lawless ones, Whose day hath come, in a time of final iniquity,", "darby": "whilst they see vanity for thee, whilst they divine a lie unto thee, to lay thee upon the necks of the wicked that are slain, whose day is come at the time of the iniquity of the end.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because ye have made your iniquity to be remembered, in that your transgressions are uncovered, so that your sins do appear in all your doings; because that ye are come to remembrance, ye shall be taken with the hand.", "acv": "while they see for thee false visions, while they divine lies to thee, to lay thee upon the necks of the wicked who are deadly wounded, whose day has come in the time of the iniquity of the end.", "anderson": "", "haweis": "", "noyes": "while they see deceit for thee, and prophesy falsehood, that it may bring thee to the necks of the wicked that are slain, whose day cometh in the time when iniquity bringeth destruction.", "webster": "While they see vanity to thee, while they divine a lie to thee, to bring thee upon the necks of [them that are] slain, of the wicked, whose day is come, when their iniquity [shall have] an end.", "vulgate": "cum tibi viderentur vana et divinarentur mendacia ut dareris super colla vulneratorum impiorum quorum venit dies in tempore iniquitatis praefinita;", "brenton": "While thou art seeing vain visions, and while thou art prophesying falsehoods, to bring thyself upon the necks of ungodly transgressors, the day is come, even an end, in a season of iniquity."}}, {"v": 30, "ref": "21:30", "o": "וְ/אַתָּה֙ חָלָ֣ל רָשָׁ֔ע נְשִׂ֖יא יִשְׂרָאֵ֑ל אֲשֶׁר בָּ֣א יוֹמ֔/וֹ בְּ/עֵ֖ת עֲוֺ֥ן קֵֽץ", "en": {"kjv": "Shall I cause it to return into his sheath? I will judge thee in the place where thou wast created, in the land of thy nativity.", "web": "Cause it to return into its sheath. In the place where you were created, in the land of your birth, will I judge you.", "bsb": "Return the sword to its sheath! In the place where you were created, in the land of your origin, I will judge you.", "asv": "Cause it to return into its sheath. In the place where thou wast created, in the land of thy birth, will I judge thee.", "ylt": "Turn it back unto its scabbard, In the place where thou wast produced, In the land of thy birth I do judge thee.", "dra": "Return into thy sheath. I will judge thee in the place wherein thou wast created, in the land of thy nativity.", "bbe": "Go back into your cover. In the place where you were made, in the land from which you were taken, I will be your judge.", "geneva": "Shall I cause it to returne into his sheath? I will iudge thee in the place where thou wast created, euen in the land of thine habitation.", "wycliffe": "in to the place in which thou were maad. Y schal deme thee in the lond of thi birthe,", "rotherham": "Put it back into its sheath! In the place where thou wast created In the land of thy nativity, will I judge thee", "darby": "Restore [it] to its sheath. I will judge thee in the place where thou wast created, in the land of thy birth.", "twenty": "", "jps": "And thou, O wicked one, that art to be slain, the prince of Israel, whose day is come, in the time of the iniquity of the end;", "acv": "Cause it to return into its sheath. In the place where thou were created, in the land of thy birth, I will judge thee.", "anderson": "", "haweis": "", "noyes": "Return the sword into its sheath! In the place where thou wast created, in the land of thy nativity, I will judge thee,", "webster": "Shall I cause [it] to return into its sheath? I will judge thee in the place where thou wast created, in the land of thy nativity.", "vulgate": "revertere ad vaginam tuam in loco in quo creatus es in terra nativitatis tuae iudicabo te;", "brenton": "Turn, rest not in this place wherein thou wert born: in thine own land will I judge thee."}}, {"v": 31, "ref": "21:31", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הָסִיר֙ הַ/מִּצְנֶ֔פֶת וְ/הָרִ֖ים הָֽ/עֲטָרָ֑ה זֹ֣את לֹא זֹ֔את הַ/שָּׁפָ֣לָה הַגְבֵּ֔הַ וְ/הַ/גָּבֹ֖הַ הַשְׁפִּֽיל", "en": {"kjv": "And I will pour out mine indignation upon thee, I will blow against thee in the fire of my wrath, and deliver thee into the hand of brutish men, and skilful to destroy.", "web": "I will pour out my indignation on you; I will blow on you with the fire of my wrath; and I will deliver you into the hand of brutish men, skillful to destroy.", "bsb": "I will pour out My anger upon you; I will breathe the fire of My fury against you; I will hand you over to brutal men, skilled in destruction.", "asv": "And I will pour out mine indignation upon thee; I will blow upon thee with the fire of my wrath; and I will deliver thee into the hand of brutish men, skilful to destroy.", "ylt": "And I have poured on thee Mine indignation, With fire of My wrath I blow against thee, And have given thee into the hand of brutish men--artificers of destruction.", "dra": "And I will pour out upon thee my indignation: in the fire of my rage will I blow upon thee, and will give thee into the hands of men that are brutish and contrive thy destruction.", "bbe": "And I will let loose my burning passion on you, breathing out on you the fire of my wrath: and I will give you up into the hands of men like beasts, trained to destruction.", "geneva": "And I wil powre out mine indignation vpon thee, and will blowe against thee in the fire of my wrath, and deliuer thee into the hand of beastly men, and skilfull to destroy.", "wycliffe": "and Y schal schede out myn indignacioun on thee; in the fier of my strong veniaunce Y schal blowe in thee, and Y schal yyue thee in to the hondis of vnwise men, and makinge deth.", "rotherham": "Then will I pour out upon thee mine indignation, With the fire of mine outburst, will I blow upon thee; and will deliver thee up into the hand of brutish men, skilled to destroy.", "darby": "And I will pour out mine indignation upon thee, I will blow upon thee the fire of my wrath, and give thee into the hand of brutish men, skilful to destroy.", "twenty": "", "jps": "thus saith the L-rd GOD: The mitre shall be removed, and the crown taken off; this shall be no more the same: that which is low shall be exalted, and that which is high abased.", "acv": "And I will pour out my indignation upon thee. I will blow upon thee with the fire of my wrath, and I will deliver thee into the hand of brutish men, skilful to destroy.", "anderson": "", "haweis": "", "noyes": "and I will pour upon thee my indignation, I will blow upon thee in the fire of my wrath, and deliver thee into the hands of brutal men, skilful to destroy.", "webster": "And I will pour out my indignation upon thee, I will blow against thee in the fire of my wrath, and deliver thee into the hand of brutish men, [and] skillful to destroy.", "vulgate": "et effundam super te indignationem meam in igne furoris mei sufflabo in te daboque te in manus hominum insipientium et fabricantium interitum;", "brenton": "And I will pour out my wrath upon thee, I will blow upon thee with the fire of my wrath, and I will deliver thee into the hands of barbarians skilled in working destruction."}}, {"v": 32, "ref": "21:32", "o": "עַוָּ֥ה עַוָּ֖ה עַוָּ֣ה אֲשִׂימֶ֑/נָּה גַּם זֹאת֙ לֹ֣א הָיָ֔ה עַד בֹּ֛א אֲשֶׁר ל֥/וֹ הַ/מִּשְׁפָּ֖ט וּ/נְתַתִּֽי/ו", "en": {"kjv": "Thou shalt be for fuel to the fire; thy blood shall be in the midst of the land; thou shalt be no more remembered: for I the Lord have spoken it.", "web": "You shall be for fuel to the fire; your blood shall be in the midst of the land; you shall be remembered no more: for I, Yahweh, have spoken it.", "bsb": "You will be fuel for the fire. Your blood will stain your own land. You will not be remembered, for I, the LORD, have spoken.’”", "asv": "Thou shalt be for fuel to the fire; thy blood shall be in the midst of the land; thou shalt be no more remembered: for I, Jehovah, have spoken it.", "ylt": "To the fire thou art for fuel, Thy blood is in the midst of the land, Thou art not remembered, For I, Jehovah, have spoken!'", "dra": "Thou shalt be fuel for the fire, thy blood shall be in the midst of the land, thou shalt be forgotten: for I the Lord have spoken it.", "bbe": "You will be food for the fire; your blood will be drained out in the land; there will be no more memory of you: for I the Lord have said it.", "geneva": "Thou shalt bee in the fire to be deuoured: thy blood shall be in the middes of the lande, and thou shalt be no more remembred: for I the Lord haue spoken it.", "wycliffe": "Thou schalt be mete to fier, thi blood schal be in the middis of erthe; thou schalt be youun to foryetyng, for Y the Lord spak.", "rotherham": "For the fire, shalt thou serve as fuel, Thy blood shall be in the midst of the land,- Thou shalt not be remembered, For I, Yahweh, have spoken.", "darby": "Thou shalt be for fuel to the fire; thy blood shall be in the midst of the land; thou shalt not be remembered: for I Jehovah have spoken.", "twenty": "", "jps": "A ruin, a ruin, a ruin, will I make it; this also shall be no more, until he come whose right it is, and I will give it him.", "acv": "Thou shall be for fuel to the fire. Thy blood shall be in the midst of the land. Thou shall no more be remembered. For I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "Thou shalt be fuel for the fire; thy blood shall be in the midst of the land; men shall no more remember thee. I, Jehovah, have spoken it.", "webster": "Thou shalt be for fuel to the fire; thy blood shall be in the midst of the land; thou shalt be no [more] remembered: for I the LORD have spoken [it].", "vulgate": "igni eris cibus sanguis tuus erit in medio terrae oblivioni traderis quia ego Dominus locutus sum;", "brenton": "Thou shalt be fuel for fire; thy blood shall be in the midst of thy land; there shall be no remembrance at all of thee: for I the Lord have spoken it."}}]}, {"c": 22, "verses": [{"v": 1, "ref": "22:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Moreover, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "22:2", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם הֲ/תִשְׁפֹּ֥ט הֲ/תִשְׁפֹּ֖ט אֶת עִ֣יר הַ/דָּמִ֑ים וְ/ה֣וֹדַעְתָּ֔/הּ אֵ֖ת כָּל תּוֹעֲבוֹתֶֽי/הָ", "en": {"kjv": "Now, thou son of man, wilt thou judge, wilt thou judge the bloody city? yea, thou shalt shew her all her abominations.", "web": "You, son of man, will you judge, will you judge the bloody city? then cause her to know all her abominations.", "bsb": "“As for you, son of man, will you judge her? Will you pass judgment on the city of bloodshed? Then confront her with all her abominations", "asv": "And thou, son of man, wilt thou judge, wilt thou judge the bloody city? then cause her to know all her abominations.", "ylt": "`And thou, son of man, dost thou judge? dost thou judge the city of blood? then thou hast caused it to know all its abominations,", "dra": "And thou son of man, dost thou not judge, dost thou not judge the city of blood?", "bbe": "And you, son of man, will you be a judge, will you be a judge of the town of blood? then make clear to her all her disgusting ways.", "geneva": "Now thou sonne of man, wilt thou iudge, wilt thou iudge this bloody citie? wilt thou shew her all her abominations?", "wycliffe": "and he seide, And thou, sone of man, whether thou demest not the citee of bloodis?", "rotherham": "Thou therefore son of man, Wilt thou judge wilt thou judge the city of bloodshed; and cause her to know all her abominations?", "darby": "And thou, son of man, wilt thou judge, wilt thou judge the bloody city? Yea, cause her to know all her abominations,", "twenty": "", "jps": "'Now, thou, son of man, wilt thou judge, wilt thou judge the bloody city? then cause her to know all her abominations.", "acv": "And thou, son of man, will thou judge, will thou judge the bloody city? Then cause her to know all her abominations.", "anderson": "", "haweis": "", "noyes": "Punish, punish, son of man, the city of blood, and show her all her abominations, and say,", "webster": "Now, thou son of man, wilt thou judge, wilt thou judge the bloody city? yes, thou shalt show her all her abominations.", "vulgate": "et tu fili hominis num iudicas num iudicas civitatem sanguinum;", "brenton": "And thou, son of man, wilt thou judge the bloody city? yea, declare thou to her all her iniquities."}}, {"v": 3, "ref": "22:3", "o": "וְ/אָמַרְתָּ֗ כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה עִ֣יר שֹׁפֶ֥כֶת דָּ֛ם בְּ/תוֹכָ֖/הּ לָ/ב֣וֹא עִתָּ֑/הּ וְ/עָשְׂתָ֧ה גִלּוּלִ֛ים עָלֶ֖י/הָ לְ/טָמְאָֽה", "en": {"kjv": "Then say thou, Thus saith the Lord God, The city sheddeth blood in the midst of it, that her time may come, and maketh idols against herself to defile herself.", "web": "You shall say, Thus says the Lord Yahweh: A city that sheds blood in the midst of her, that her time may come, and that makes idols against herself to defile her!", "bsb": "and tell her that this is what the Lord GOD says: ‘O city who brings her own doom by shedding blood within her walls and making idols to defile herself,", "asv": "And thou shalt say, Thus saith the Lord Jehovah: A city that sheddeth blood in the midst of her, that her time may come, and that maketh idols against herself to defile her!", "ylt": "and thou hast said: Thus said the Lord Jehovah: The city is shedding blood in its midst, For the coming in of its time, And it hath made idols on it for defilement.", "dra": "And thou shalt shew her all her abominations, and shalt say: Thus saith the Lord God: This is the city that sheddeth blood in the midst of her, that her time may come: and that hath made idols against herself, to defile herself.", "bbe": "And you are to say, This is what the Lord has said: A town causing blood to be drained out in her streets so that her time may come, and making images in her to make her unclean!", "geneva": "Then say, Thus sayth the Lord God, The citie sheddeth blood in the middes of it, that her time may come, and maketh idols against her selfe to pollute her selfe.", "wycliffe": "And thou schalt schewe to it alle hise abhomynaciouns, and thou schalt seie, The Lord God seith these thingis, This is a citee schedinge out blood in the myddis of it silf, that the tyme therof come; and which made idols ayens it silf, that it shulde be defoulid.", "rotherham": "Thou shalt say then Thus saith My Lord. Yahweh, A city shedding blood in her own midst That her time might come, Therefore hath she been making manufactured gods for herself, to be defiled.", "darby": "and say, Thus saith the Lord Jehovah: A city that sheddeth blood in her midst, that her time may come, and maketh idols against herself to defile herself.", "twenty": "", "jps": "And thou shalt say: Thus saith the L-rd GOD: O city that sheddest blood in the midst of thee, that thy time may come, and that makest idols unto thyself to defile thee;", "acv": "And thou shall say, Thus says the lord Jehovah: A city that sheds blood in the midst of her, that her time may come, and who makes idols against herself to defile her!", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: O city that sheddest blood in the midst of thee, that thy time may come, and makest idols to defile thyself!", "webster": "Then say thou, Thus saith the Lord GOD; The city sheddeth blood in the midst of it, that her time may come, and maketh idols against herself to defile herself.", "vulgate": "et ostendes ei omnes abominationes suas et dices haec dicit Dominus Deus civitas effundens sanguinem in medio sui ut veniat tempus eius et quae fecit idola contra semet ipsam ut pollueretur;", "brenton": "And thou shalt say, Thus saith the Lord God: O city that sheds blood in the midst of her, so that her time should come, and that forms devices against herself, to defile herself;"}}, {"v": 4, "ref": "22:4", "o": "בְּ/דָמֵ֨/ךְ אֲשֶׁר שָׁפַ֜כְתְּ אָשַׁ֗מְתְּ וּ/בְ/גִלּוּלַ֤יִ/ךְ אֲשֶׁר עָשִׂית֙ טָמֵ֔את וַ/תַּקְרִ֣יבִי יָמַ֔יִ/ךְ וַ/תָּב֖וֹא עַד שְׁנוֹתָ֑יִ/ךְ עַל כֵּ֗ן נְתַתִּ֤י/ךְ חֶרְפָּה֙ לַ/גּוֹיִ֔ם וְ/קַלָּסָ֖ה לְ/כָל הָ/אֲרָצֽוֹת", "en": {"kjv": "Thou art become guilty in thy blood that thou hast shed; and hast defiled thyself in thine idols which thou hast made; and thou hast caused thy days to draw near, and art come even unto thy years: therefore have I made thee a reproach unto the heathen, and a mocking to all countries.", "web": "You have become guilty in your blood that you have shed, and are defiled in your idols which you have made; and you have caused your days to draw near, and have come even to your years: therefore have I made you a reproach to the nations, and a mocking to all the countries.", "bsb": "you are guilty of the blood you have shed, and you are defiled by the idols you have made. You have brought your days to a close and have come to the end of your years. Therefore I have made you a reproach to the nations and a mockery to all the lands.", "asv": "Thou art become guilty in thy blood that thou hast shed, and art defiled in thine idols which thou hast made; and thou hast caused thy days to draw near, and art come even unto thy years: therefore have I made thee a reproach unto the nations, and a mocking to all the countries.", "ylt": "By thy blood that thou hast shed thou hast been guilty, And by thine idols that thou hast made thou hast been defiled, And thou causest thy days to draw near, And art come in unto thine years, Therefore I have given thee a reproach to nations, And a derision to all the lands.", "dra": "Thou art become guilty in thy blood which thou hast shed: and thou art defiled in thy idols which thou hast made: and thou hast made thy days to draw near, and hast brought on the time of thy years: therefore have I made thee a reproach to the Gentiles, and a mockery to all countries.", "bbe": "You are responsible for the blood drained out by you, and you are unclean through the images which you have made; and you have made your day come near, and the time of your judging has come; for this cause I have made you a name of shame to the nations and a cause of laughing to all countries.", "geneva": "Thou hast offended in thy blood, that thou hast shed, and hast polluted thy selfe in thine idols, which thou hast made, and thou hast caused thy dayes to draw neere, and art come vnto thy terme: therefore haue I made thee a reproch to the heathen, and a mocking to all countreys.", "wycliffe": "In thi blood which is shed out of thee, thou trespassidist, and thou art defoulid in thin idols whiche thou madist; and thou madist thi daies to neiye, and thou brouytist the time of thi yeeris. Therfor Y yaf thee schenschipe to hethene men, and scornyng to alle londis that ben niy thee,", "rotherham": "Because of the blood which thou hast shed, hast thou become guilty. And with the manufactured gods which thou hast made, hast thou defiled thyself, Thus hast thou brought near thy days, And hast come unto thy years,— For this cause, have I delivered thee As a reproach to the nations, And as a derision to all the lands.", "darby": "Thou art become guilty by thy blood which thou hast shed, and hast defiled thyself with thine idols which thou hast made; and thou hast caused thy days to draw near, and art come unto thy years: therefore have I made thee a reproach unto the nations, and a mocking unto all countries.", "twenty": "", "jps": "thou art become guilty in thy blood that thou hast shed, and art defiled in thine idols which thou hast made; and thou hast caused thy days to draw near, and art come even unto thy years; therefore have I made thee a reproach unto the nations, and a mocking to all the countries!", "acv": "Thou have become guilty in thy blood that thou have shed, and are defiled in thine idols which thou have made. And thou have caused thy days to draw near, and have come even to thy years. Therefore I have made thee a reproach to the nations, and a mocking to all the countries.", "anderson": "", "haweis": "", "noyes": "Through the blood which thou sheddest thou bringest guilt upon thyself, and through the idols which thou makest thou pollutest thyself, and thou causest thy days to draw near, and comest to thy years. Therefore do I make thee a reproach to the nations, and a derision to all countries.", "webster": "Thou art become guilty in thy blood that thou hast shed; and hast defiled thyself by thy idols which thou hast made; and thou hast caused thy days to draw near, and art come [even] to thy years: therefore have I made thee a reproach to the heathen, and a mocking to all countries.", "vulgate": "in sanguine tuo qui a te effusus est deliquisti et in idolis tuis quae fecisti polluta es et adpropinquare fecisti dies tuos et adduxisti tempus annorum tuorum propterea dedi te obprobrium gentibus et inrisionem universis terris;", "brenton": "in their blood which thou hast shed, thou hast transgressed; and in thy devices which thou hast formed, thou hast polluted thyself; and thou hast brought nigh thy days, and hast brought on the time of thy years: therefore have I made thee a reproach to the Gentiles, and a mockery to all the countries,"}}, {"v": 5, "ref": "22:5", "o": "הַ/קְּרֹב֛וֹת וְ/הָ/רְחֹק֥וֹת מִמֵּ֖/ךְ יִתְקַלְּסוּ בָ֑/ךְ טְמֵאַ֣ת הַ/שֵּׁ֔ם רַבַּ֖ת הַ/מְּהוּמָֽה", "en": {"kjv": "Those that be near, and those that be far from thee, shall mock thee, which art infamous and much vexed.", "web": "Those who are near, and those who are far from you, shall mock you, you infamous one, full of tumult.", "bsb": "Those near and far will mock you, O infamous city, full of turmoil.", "asv": "Those that are near, and those that are far from thee, shall mock thee, thou infamous one and full of tumult.", "ylt": "The near and the far-off from thee scoff at thee, O defiled of name--abounding in trouble.", "dra": "Those that are near, and those that are far from thee, shall triumph over thee: thou filthy one, infamous, great in destruction.", "bbe": "Those who are near and those who are far from you will make sport of you; your name is unclean, you are full of sounds of fear.", "geneva": "Those that be neere, and those that be farre from thee, shall mocke thee, which art vile in name and sore in affliction.", "wycliffe": "and that ben fer fro thee; thou foul citee, noble, greet in perisching, thei schulen haue victorie of thee.", "rotherham": "They who are near and they who are far off from thee shall shew themselves derisive over thee,— O thou of impure name, abounding in confusion!", "darby": "Those that are near, and those that are far from thee, shall mock thee, who art infamous [and] full of tumult.", "twenty": "", "jps": "Those that are near, and those that are far from thee, shall mock thee, thou defiled of name and full of tumult.", "acv": "Those that are near, and those that are far from thee, shall mock thee, thou infamous one, full of tumult.", "anderson": "", "haweis": "", "noyes": "Those that are near, and those that are far from thee, shall mock thee as infamous, full of confusion.", "webster": "[Those that are] near, and [those that are] far from thee, shall mock thee, [who art] infamous [and] much troubled.", "vulgate": "quae iuxta sunt et quae procul a te triumphabunt de te sordida nobilis grandis interitu;", "brenton": "to those near thee, and to those far distant from thee; and they shall mock thee, thou that art notoriously unclean, and abundant in iniquities."}}, {"v": 6, "ref": "22:6", "o": "הִנֵּה֙ נְשִׂיאֵ֣י יִשְׂרָאֵ֔ל אִ֥ישׁ לִ/זְרֹע֖/וֹ הָ֣יוּ בָ֑/ךְ לְמַ֖עַן שְׁפָךְ דָּֽם", "en": {"kjv": "Behold, the princes of Israel, every one were in thee to their power to shed blood.", "web": "Behold, the princes of Israel, everyone according to his power, have been in you to shed blood.", "bsb": "See how every prince of Israel within you has used his power to shed blood.", "asv": "Behold, the princes of Israel, every one according to his power, have been in thee to shed blood.", "ylt": "Lo, princes of Israel--each according to his arm Have been in thee to shed blood.", "dra": "Behold the princes of Israel, every one hath employed his arm in thee to shed blood.", "bbe": "See, the rulers of Israel, every one in his family, have been causing death in you.", "geneva": "Beholde, the princes of Israel euery one in thee was ready to his power, to shed blood.", "wycliffe": "Lo! princes of Israel, alle in her arm, weren in thee, to schede out blood.", "rotherham": "Lo! the princes of Israel, every man for his own arm, have they been in thee, For the sake of shedding blood.", "darby": "Behold, the princes of Israel have been in thee to shed blood, each according to his power.", "twenty": "", "jps": "Behold, the princes of Israel, every one according to his might, have been in thee to shed blood.", "acv": "Behold, the rulers of Israel, each one according to his power, have been in thee to shed blood.", "anderson": "", "haweis": "", "noyes": "Behold the princes of Israel are engaged every one according to his strength within thee to shed blood.", "webster": "Behold, the princes of Israel, every one were in thee to their power to shed blood.", "vulgate": "ecce principes Israhel singuli in brachio suo fuerunt in te ad effundendum sanguinem;", "brenton": "Behold, the princes of the house of Israel have conspired in thee each one with his kindred, that they might shed blood."}}, {"v": 7, "ref": "22:7", "o": "אָ֤ב וָ/אֵם֙ הֵקַ֣לּוּ בָ֔/ךְ לַ/גֵּ֛ר עָשׂ֥וּ בַ/עֹ֖שֶׁק בְּ/תוֹכֵ֑/ךְ יָת֥וֹם וְ/אַלְמָנָ֖ה ה֥וֹנוּ בָֽ/ךְ", "en": {"kjv": "In thee have they set light by father and mother: in the midst of thee have they dealt by oppression with the stranger: in thee have they vexed the fatherless and the widow.", "web": "In you have they set light by father and mother; in your midst have they dealt by oppression with the foreigner; in you have they wronged the fatherless and the widow.", "bsb": "Father and mother are treated with contempt. Within your walls the foreign resident is exploited, the fatherless and the widow are oppressed.", "asv": "In thee have they set light by father and mother; in the midst of thee have they dealt by oppression with the sojourner; in thee have they wronged the fatherless and the widow.", "ylt": "Father and mother made light of in thee, To a sojourner they dealt oppressively in thy midst, Fatherless and widow they oppressed in thee.", "dra": "They have abused father and mother in thee, they have oppressed the stranger in the midst of thee, they have grieved the fatherless and widow in thee.", "bbe": "In you they have had no respect for father and mother; in you they have been cruel to the man from a strange land; in you they have done wrong to the child without a father and to the widow.", "geneva": "In thee haue they despised father and mother: in the middes of thee haue they oppressed the stranger: in thee haue they vexed the fatherlesse and the widowe.", "wycliffe": "Thei punyschiden with wrongis fadir and modir in thee, thei calengiden falsli a comelyng in the myddis of thee, thei maden sori a fadirles child and a widewe at thee.", "rotherham": "Father and mother, have they despised in thee, To the sojourner, have they dealt with oppression in the midst of thee,— The fatherless and the widow, have they maltreated in thee:", "darby": "In thee have they made light of father and mother; in the midst of thee have they dealt by oppression with the stranger; in thee have they vexed the fatherless and the widow.", "twenty": "", "jps": "In thee have they made light of father and mother; in the midst of thee have they dealt by oppression with the stranger; in thee have they wronged the fatherless and the widow.", "acv": "In thee they have made light of father and mother. In the midst of thee they have dealt with the sojourner by oppression. In thee they have wronged the fatherless and the widow.", "anderson": "", "haweis": "", "noyes": "In thee they set light by father and mother; in thee are they guilty of oppression to the stranger; in thee do they oppress the fatherless and the widow.", "webster": "In thee have they set light by father and mother: in the midst of thee have they dealt by oppression with the stranger: in thee have they oppressed the fatherless and the widow.", "vulgate": "patrem et matrem contumeliis adfecerunt in te advenam calumniati sunt in medio tui pupillum et viduam contristaverunt apud te;", "brenton": "In thee they have reviled father and mother; and in thee they have behaved unjustly toward the stranger: they have oppressed the orphan and widow."}}, {"v": 8, "ref": "22:8", "o": "קָדָשַׁ֖/י בָּזִ֑ית וְ/אֶת שַׁבְּתֹתַ֖/י חִלָּֽלְתְּ", "en": {"kjv": "Thou hast despised mine holy things, and hast profaned my sabbaths.", "web": "You have despised my holy things, and have profaned my Sabbaths.", "bsb": "You have despised My holy things and profaned My Sabbaths.", "asv": "Thou hast despised my holy things, and hast profaned my sabbaths.", "ylt": "My holy things thou hast despised, And My sabbaths thou hast polluted.", "dra": "Thou hast despised my sanctuaries, and profaned my sabbaths.", "bbe": "You have made little of my holy things, and have made my Sabbaths unclean.", "geneva": "Thou hast despised mine holy things, and hast polluted my Sabbaths.", "wycliffe": "Ye dispisiden my seyntuaries, and ye defouliden my sabatis.", "rotherham": "My holy things, hast thou despised,- And my sabbaths, hast thou profaned:", "darby": "Thou hast despised my holy things, and hast profaned my sabbaths.", "twenty": "", "jps": "Thou hast despised My holy things, and hast profaned My sabbaths.", "acv": "Thou have despised my holy things, and have profaned my sabbaths.", "anderson": "", "haweis": "", "noyes": "Thou hast despised my holy things, and profaned my sabbaths.", "webster": "Thou hast despised my holy things, and hast profaned my sabbaths.", "vulgate": "sanctuaria mea sprevistis et sabbata mea polluistis;", "brenton": "And they have set at nought my holy things, and in thee they have profaned my sabbaths."}}, {"v": 9, "ref": "22:9", "o": "אַנְשֵׁ֥י רָכִ֛יל הָ֥יוּ בָ֖/ךְ לְמַ֣עַן שְׁפָךְ דָּ֑ם וְ/אֶל הֶֽ/הָרִים֙ אָ֣כְלוּ בָ֔/ךְ זִמָּ֖ה עָשׂ֥וּ בְ/תוֹכֵֽ/ךְ", "en": {"kjv": "In thee are men that carry tales to shed blood: and in thee they eat upon the mountains: in the midst of thee they commit lewdness.", "web": "Slanderous men have been in you to shed blood; and in you they have eaten on the mountains: in your midst they have committed lewdness.", "bsb": "Among you are slanderous men bent on bloodshed; within you are those who eat on the mountain shrines and commit acts of indecency.", "asv": "Slanderous men have been in thee to shed blood; and in thee they have eaten upon the mountains: in the midst of thee they have committed lewdness.", "ylt": "Men of slander have been in thee to shed blood, And on the mountains they have eaten in thee, Wickedness they have done in thy midst.", "dra": "Slanderers have been in thee to shed blood, and they have eaten upon the mountains in thee, they have committed wickedness in the midst of thee.", "bbe": "In you there are men who say evil of others, causing death; in you they have taken the flesh with the blood for food; in your streets they have put evil designs into effect.", "geneva": "In thee are men that cary tales to shed blood: in thee are they that eate vpon the mountaines: in ye mids of thee they comit abomination.", "wycliffe": "Men bacbiteris weren in thee, to schede out blood, and eten on hillis in thee; thei wrouyten greet trespas in the myddis of thee.", "rotherham": "Slanders, have arisen in thee For the sake of shedding blood,- And unto the mountains, have they eaten in thee, Lewdness, have they practised in the midst of thee:", "darby": "In thee there have been slanderous men to shed blood; and in thee have they eaten upon the mountains; in the midst of thee they have committed lewdness;", "twenty": "", "jps": "In thee have been talebearers to shed blood; and in thee they have eaten upon the mountains; in the midst of thee they have committed lewdness.", "acv": "Slanderous men have been in thee to shed blood, and in thee they have eaten upon the mountains. In the midst of thee they have committed lewdness.", "anderson": "", "haweis": "", "noyes": "In thee are men who carry tales, that they may shed blood; in thee do they eat upon the mountains; in the midst of thee do they commit lewdness.", "webster": "In thee are men that carry tales to shed blood: and in thee they eat upon the mountains: in the midst of thee they commit lewdness.", "vulgate": "viri detractores fuerunt in te ad effundendum sanguinem et super montes comederunt in te scelus operati sunt in medio tui;", "brenton": "There are robbers in thee, to shed blood in thee; and in thee they have eaten upon the mountains: they have wrought ungodliness in the midst of thee."}}, {"v": 10, "ref": "22:10", "o": "עֶרְוַת אָ֖ב גִּלָּה בָ֑/ךְ טְמֵאַ֥ת הַ/נִּדָּ֖ה עִנּוּ בָֽ/ךְ", "en": {"kjv": "In thee have they discovered their fathers’ nakedness: in thee have they humbled her that was set apart for pollution.", "web": "In you have they uncovered their fathers’ nakedness; in you have they humbled her who was unclean in her impurity.", "bsb": "In you they have uncovered the nakedness of their fathers; in you they violate women during their menstrual impurity.", "asv": "In thee have they uncovered their fathers’ nakedness; in thee have they humbled her that was unclean in her impurity.", "ylt": "The nakedness of a father hath one uncovered in thee, The defiled of impurity they humbled in thee.", "dra": "They have discovered the nakedness of their father in thee, they have humbled the uncleanness of the menstruous woman in thee.", "bbe": "In you they have let the shame of their fathers be seen; in you they have done wrong to a woman at the time when she was unclean.", "geneva": "In thee haue they discouered their fathers shame: in thee haue they vexed her that was polluted in her floures.", "wycliffe": "Thei vnhiliden the schamefulere thingis of the fadir in thee, thei maden low in thee the vnclenesse of a womman in vnclene blood.", "rotherham": "A father’s shame hath been uncovered in thee, Her that was unclean in her removal, have they humbled in thee;", "darby": "in thee have they discovered their fathers' nakedness; in thee have they humbled her that was unclean in her separation.", "twenty": "", "jps": "In thee have they uncovered their fathers' nakedness; in thee have they humbled her that was unclean in her impurity.", "acv": "In thee they have uncovered their fathers' nakedness. In thee they have humbled her who was unclean in her impurity.", "anderson": "", "haweis": "", "noyes": "In thee doth the son uncover the father’s nakedness; in thee do they lie with a woman in her uncleanness.", "webster": "In thee have they uncovered their fathers' nakedness: in thee have they humbled her that was set apart for pollution.", "vulgate": "verecundiora patris discoperuerunt in te inmunditiam menstruatae humiliaverunt in te;", "brenton": "In thee they have uncovered the father's shame; and in thee they have humbled her that was set apart for uncleanness."}}, {"v": 11, "ref": "22:11", "o": "וְ/אִ֣ישׁ אֶת אֵ֣שֶׁת רֵעֵ֗/הוּ עָשָׂה֙ תּֽוֹעֵבָ֔ה וְ/אִ֥ישׁ אֶת כַּלָּת֖/וֹ טִמֵּ֣א בְ/זִמָּ֑ה וְ/אִ֛ישׁ אֶת אֲחֹת֥/וֹ בַת אָבִ֖י/ו עִנָּה בָֽ/ךְ", "en": {"kjv": "And one hath committed abomination with his neighbour’s wife; and another hath lewdly defiled his daughter in law; and another in thee hath humbled his sister, his father’s daughter.", "web": "One has committed abomination with his neighbor’s wife; and another has lewdly defiled his daughter-in-law; and another in you has humbled his sister, his father’s daughter.", "bsb": "One man commits an abomination with his neighbor’s wife; another wickedly defiles his daughter-in-law; and yet another violates his sister, his own father’s daughter.", "asv": "And one hath committed abomination with his neighbor’s wife; and another hath lewdly defiled his daughter-in-law; and another in thee hath humbled his sister, his father’s daughter.", "ylt": "And each with the wife of his neighbour hath done abomination, And each his daughter-in-law hath defiled through wickedness, And each his sister, his father's daughter, hath humbled in thee.", "dra": "And every one hath committed abomination with his neighbour's wife, and the father in law hath wickedly defiled his daughter in law, the brother hath oppressed his sister the daughter of his father in thee.", "bbe": "And in you one man has done what was disgusting with his neighbour's wife; and another has made his daughter-in-law unclean; and another has done wrong to his sister, his father's daughter.", "geneva": "And euery one hath committed abomination with his neighbours wife, and euery one hath wickedly defiled his daughter in lawe, and in thee hath euery man forced his owne sister, euen his fathers daughter.", "wycliffe": "And ech man wrouyte abhomynacioun ayens the wijf of his neiybore, and the fadir of the hosebonde defoulide his sones wijf vnleuefuli; a brother oppresside in thee his sister, the douytir of his fadir.", "rotherham": "And, one man, with the wife of his neighbour, hath wrought abomination, And another, hath defiled, his daughter-in-law, by shameful deed,— And another, his own sister daughter of his own father, hath humbled in thee:", "darby": "And one hath committed abomination with his neighbour's wife; and another hath lewdly defiled his daughter-in-law; and another in thee hath humbled his sister, his father's daughter.", "twenty": "", "jps": "And each hath committed abomination with his neighbour's wife; and each hath lewdly defiled his daughter-in-law; and each in thee hath humbled his sister, his father's daughter.", "acv": "And one has committed abomination with his neighbor's wife, and another has lewdly defiled his daughter-in-law, and another in thee has humbled his sister, his father's daughter.", "anderson": "", "haweis": "", "noyes": "And one committeth abomination with his neighbor’s wife; and another, with incestuous lewdness, defileth his daughter-in-law; and in thee another lieth with his sister, his father’s daughter.", "webster": "And one hath committed abomination with his neighbor's wife; and another hath lewdly defiled his daughter-in-law; and another in thee hath humbled his sister, his father's daughter.", "vulgate": "et unusquisque in uxorem proximi sui operatus est abominationem et socer nurum suam polluit nefarie frater sororem suam filiam patris sui oppressit in te;", "brenton": "They have dealt unlawfully each one with his neighbor's wife; and each one in ungodliness has defiled his daughter-in-law: and in thee they have humbled each one his sister, the daughter of his father."}}, {"v": 12, "ref": "22:12", "o": "שֹׁ֥חַד לָֽקְחוּ בָ֖/ךְ לְמַ֣עַן שְׁפָךְ דָּ֑ם נֶ֧שֶׁךְ וְ/תַרְבִּ֣ית לָקַ֗חַתְּ וַ/תְּבַצְּעִ֤י רֵעַ֨יִ/ךְ֙ בַּ/עֹ֔שֶׁק וְ/אֹתִ֣/י שָׁכַ֔חַתְּ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "In thee have they taken gifts to shed blood; thou hast taken usury and increase, and thou hast greedily gained of thy neighbours by extortion, and hast forgotten me, saith the Lord God.", "web": "In you have they taken bribes to shed blood; you have taken interest and increase, and you have greedily gained of your neighbors by oppression, and have forgotten me, says the Lord Yahweh.", "bsb": "In you they take bribes to shed blood. You engage in usury, take excess interest, and extort your neighbors. But Me you have forgotten, declares the Lord GOD.", "asv": "In thee have they taken bribes to shed blood; thou hast taken interest and increase, and thou hast greedily gained of thy neighbors by oppression, and hast forgotten me, saith the Lord Jehovah.", "ylt": "A bribe they have taken in thee to shed blood, Usury and increase thou hast taken, And cuttest off thy neighbour by oppression, And Me thou hast forgotten, An affirmation of the Lord Jehovah!", "dra": "They have taken gifts in thee to shed blood: thou hast taken usury and increase, and hast covetously oppressed thy neighbours: and thou hast forgotten me, saith the Lord God.", "bbe": "In you they have taken rewards as the price of blood; you have taken interest and great profits, and you have taken away your neighbours' goods by force, and have not kept me in mind, says the Lord.", "geneva": "In thee haue they taken giftes to shed blood: thou hast taken vsurie and the encrease, and thou hast defrauded thy neighbours by extortion, and hast forgotten me, saith the Lord God.", "wycliffe": "Thei token yiftis at thee, to schede out blood; thou tokist vsure and ouerabundaunce, and thou calengidist greedili thi neiyboris, and thou hast foryete me, seith the Lord God.", "rotherham": "Bribes, have they accepted in thee, For the sake of shedding blood,-Interest and increase, hast thou accepted And thou hast overreached thy neighbour by oppression, And me, hast thou forgotten, Declareth My Lord Yahweh.", "darby": "In thee have they taken gifts to shed blood; thou hast taken usury and increase, and thou hast overreached thy neighbours by oppression, and hast forgotten me, saith the Lord Jehovah.", "twenty": "", "jps": "In thee have they taken gifts to shed blood; thou hast taken interest and increase, and thou hast greedily gained of thy neighbours by oppression, and hast forgotten Me, saith the L-rd GOD.", "acv": "In thee they have taken bribes to shed blood. Thou have taken interest and increase. And thou have greedily gained from thy neighbors by oppression, and have forgotten me, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "In thee do they take a reward to shed blood. Thou takest usury and increase, and thou hast enriched thyself from thy neighbor by extortion, and hast forgotten me, saith the Lord Jehovah.", "webster": "In thee have they taken gifts to shed blood; thou hast taken interest and increase, and thou hast greedily gained from thy neighbors by extortion, and hast forgotten me, saith the Lord GOD.", "vulgate": "munera acceperunt apud te ad effundendum sanguinem usuram et superabundantiam accepisti et avare proximos tuos calumniabaris meique oblita es ait Dominus Deus;", "brenton": "In thee they have received gifts to shed blood; they have received in thee interest and usurious increase; and by oppression thou hast brought thy wickedness to the full, and hast forgotten me, saith the Lord."}}, {"v": 13, "ref": "22:13", "o": "וְ/הִנֵּה֙ הִכֵּ֣יתִי כַפִּ֔/י אֶל בִּצְעֵ֖/ךְ אֲשֶׁ֣ר עָשִׂ֑ית וְ/עַ֨ל דָּמֵ֔/ךְ אֲשֶׁ֥ר הָי֖וּ בְּ/תוֹכֵֽ/ךְ", "en": {"kjv": "Behold, therefore I have smitten mine hand at thy dishonest gain which thou hast made, and at thy blood which hath been in the midst of thee.", "web": "Behold, therefore, I have struck my hand at your dishonest gain which you have made, and at your blood which has been in your midst.", "bsb": "Now look, I strike My hands together against your unjust gain and against the blood you have shed in your midst.", "asv": "Behold, therefore, I have smitten my hand at thy dishonest gain which thou hast made, and at thy blood which hath been in the midst of thee.", "ylt": "And lo, I have smitten My hand, Because of thy dishonest gain that thou hast gained, And for thy blood that hath been in thy midst.", "dra": "Behold, I have clapped my hands at thy covetousness, which thou hast exercised: and at the blood that hath been shed in the midst of thee.", "bbe": "See, then, I have made my hands come together in wrath against your taking of goods by force and against the blood which has been flowing in you.", "geneva": "Beholde, therefore I haue smitten mine hands vpon thy couetousnesse, that thou hast vsed, and vpon the blood, which hath bene in the middes of thee.", "wycliffe": "Lo! Y haue smyte togidere myn hondis on thin aueryce, which thou didist, and on the blood which is sched out in the myddis of thee.", "rotherham": "Lo! therefore I have smitten my hand, At thine unjust gain which thou hast made— And over thy bloodshed, which they have caused in thy midst.", "darby": "And behold, I have smitten mine hand at thine overreaching which thou hast done, and at thy bloodshed which hath been in the midst of thee.", "twenty": "", "jps": "Behold, therefore, I have smitten My hand at thy dishonest gain which thou hast made, and at thy blood which hath been in the midst of thee.", "acv": "Behold, therefore, I have smitten my hand at thy dishonest gain which thou have made, and at thy blood which has been in the midst of thee.", "anderson": "", "haweis": "", "noyes": "Therefore, behold, I have smitten my hands together at thy dishonest gain which thou hast made, and at the blood which hath been shed in the midst of thee.", "webster": "Behold, therefore I have smitten my hand at thy dishonest gain which thou hast made, and at thy blood which hath been in the midst of thee.", "vulgate": "ecce conplosi manus meas super avaritiam tuam quam fecisti et super sanguinem qui effusus est in medio tui;", "brenton": "And if I shall smite my hand at thine iniquities which thou hast accomplished, which thou hast wrought, and at thy blood that has been shed in the midst of thee,"}}, {"v": 14, "ref": "22:14", "o": "הֲ/יַעֲמֹ֤ד לִבֵּ/ךְ֙ אִם תֶּחֱזַ֣קְנָה יָדַ֔יִ/ךְ לַ/יָּמִ֕ים אֲשֶׁ֥ר אֲנִ֖י עֹשֶׂ֣ה אוֹתָ֑/ךְ אֲנִ֥י יְהוָ֖ה דִּבַּ֥רְתִּי וְ/עָשִֽׂיתִי", "en": {"kjv": "Can thine heart endure, or can thine hands be strong, in the days that I shall deal with thee? I the Lord have spoken it, and will do it.", "web": "Can your heart endure, or can your hands be strong, in the days that I shall deal with you? I, Yahweh, have spoken it, and will do it.", "bsb": "Will your courage endure or your hands be strong in the day I deal with you? I, the LORD, have spoken, and I will act.", "asv": "Can thy heart endure, or can thy hands be strong, in the days that I shall deal with thee? I, Jehovah, have spoken it, and will do it.", "ylt": "Doth thy heart stand--are thy hands strong, For the days that I am dealing with thee? I, Jehovah, have spoken and have done it .", "dra": "Shall thy heart endure, or shall thy hands prevail in the days which I will bring upon thee: I the Lord have spoken, and will do it.", "bbe": "Will your heart be high or your hands strong in the days when I take you in hand? I the Lord have said it and will do it.", "geneva": "Can thine heart endure, or can thine hands be strong, in the dayes that I shall haue to doe with thee? I the Lord haue spoken it, and will doe it.", "wycliffe": "Whether thin herte schal susteyne, ether thin hondis schulen haue power in the daies whiche Y schal make to thee? For Y the Lord spak, and Y schal do.", "rotherham": "Can thy heart endure or can thy hands be strong in the days when I am dealing with thee? I. Yahweh have spoken and will perform.", "darby": "Shall thy heart endure, shall thy hands be strong, in the days that I shall deal with thee? I Jehovah have spoken, and will do [it].", "twenty": "", "jps": "Can thy heart endure, or can thy hands be strong, in the days that I shall deal with thee? I HaShem have spoken it, and will do it.", "acv": "Can thy heart endure, or can thy hands be strong, in the days that I shall deal with thee? I, Jehovah, have spoken it, and will do it.", "anderson": "", "haweis": "", "noyes": "Can thy heart endure, or can thy hands be strong, in the day when I shall deal with thee? I, Jehovah, have spoken it, and will do it.", "webster": "Can thy heart endure, or can thy hands be strong, in the days that I shall deal with thee? I the LORD have spoken [it], and will do [it].", "vulgate": "numquid sustinebit cor tuum aut praevalebunt manus tuae in diebus quos ego faciam tibi ego Dominus locutus sum et faciam;", "brenton": "shall thy heart endure? shall thine hands be strong in the days which I bring upon thee? I the Lord have spoken, and will do it."}}, {"v": 15, "ref": "22:15", "o": "וַ/הֲפִיצוֹתִ֤י אוֹתָ/ךְ֙ בַּ/גּוֹיִ֔ם וְ/זֵרִיתִ֖י/ךְ בָּ/אֲרָצ֑וֹת וַ/הֲתִמֹּתִ֥י טֻמְאָתֵ֖/ךְ מִמֵּֽ/ךְ", "en": {"kjv": "And I will scatter thee among the heathen, and disperse thee in the countries, and will consume thy filthiness out of thee.", "web": "I will scatter you among the nations, and disperse you through the countries; and I will consume your filthiness out of you.", "bsb": "I will disperse you among the nations and scatter you throughout the lands; I will purge your uncleanness.", "asv": "And I will scatter thee among the nations, and disperse thee through the countries; and I will consume thy filthiness out of thee.", "ylt": "And I have scattered thee among nations, And have spread thee out among lands, And consumed thy uncleanness out of thee.", "dra": "And I will disperse thee in the nations, and will scatter thee among the countries, and I will put an end to thy uncleanness in thee.", "bbe": "And I will send you in flight among the nations and wandering among the countries; and I will completely take away out of you everything which is unclean.", "geneva": "And I wil scatter thee among the heathen, and disperse thee in the countreys, and will cause thy filthines to cease from thee.", "wycliffe": "And Y schal scatere thee in to naciouns, and Y schal wyndewe thee in to londis; and Y schal make thin vnclennesse to faile fro thee,", "rotherham": "Therefore will I disperse thee among the nations, And scatter thee throughout the lands,— And will cause to cease thine impurity out of thee;", "darby": "And I will scatter thee among the nations, and disperse thee through the countries, and will consume thy filthiness out of thee.", "twenty": "", "jps": "And I will scatter thee among the nations, and disperse thee through the countries; and I will consume thy filthiness out of thee.", "acv": "And I will scatter thee among the nations, and disperse thee through the countries, and I will consume thy filthiness out of thee.", "anderson": "", "haweis": "", "noyes": "I will scatter thee among the nations, and disperse thee in the countries, and will consume thine impurity out of thee;", "webster": "And I will scatter thee among the heathen, and disperse thee in the countries, and will consume thy filthiness out of thee.", "vulgate": "et dispergam te in nationes et ventilabo te in terras et deficere faciam inmunditiam tuam a te;", "brenton": "And I will scatter thee among the nations, and disperse thee in the countries, and thy uncleanness shall be removed out of thee."}}, {"v": 16, "ref": "22:16", "o": "וְ/נִחַ֥לְתְּ בָּ֖/ךְ לְ/עֵינֵ֣י גוֹיִ֑ם וְ/יָדַ֖עַתְּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And thou shalt take thine inheritance in thyself in the sight of the heathen, and thou shalt know that I am the Lord.", "web": "You shall be profaned in yourself, in the sight of the nations; and you shall know that I am Yahweh.", "bsb": "And when you have defiled yourself in the eyes of the nations, then you will know that I am the LORD.’”", "asv": "And thou shalt be profaned in thyself, in the sight of the nations; and thou shalt know that I am Jehovah.", "ylt": "And thou hast been polluted in thyself Before the eyes of nations, And thou hast known that I am Jehovah.'", "dra": "And I will possess thee in the sight of the Gentiles, and thou shalt know that I am the Lord.", "bbe": "And you will be made low before the eyes of the nations; and it will be clear to you that I am the Lord.", "geneva": "And thou shalt take thine inheritance in thy selfe in the sight of the heathen, and thou shalt knowe that I am the Lord.", "wycliffe": "and Y schal welde thee in the siyt of hethene men; and thou schalt wite, that Y am the Lord.", "rotherham": "So shalt thou be profaned in thyself, before the eyes of nations, Thus shalt thou know that, I, am Yahweh.", "darby": "And thou shalt be polluted through thyself in the sight of the nations, and thou shalt know that I [am] Jehovah.", "twenty": "", "jps": "And thou shalt be profaned in thyself, in the sight of the nations; and thou shalt know that I am HaShem.'", "acv": "And thou shall be profaned in thyself, in the sight of the nations. And thou shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "and thou shalt through thyself be profaned before the eyes of the nations, and thou shalt know that I am Jehovah.", "webster": "And thou shalt take thy inheritance in thyself in the sight of the heathen, and thou shalt know that I [am] the LORD.", "vulgate": "et possidebo te in conspectu gentium et scies quia ego Dominus;", "brenton": "And I will give heritages in thee in the sight of the nations, and ye shall know that I am the Lord."}}, {"v": 17, "ref": "22:17", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying, `Son of man,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide,", "rotherham": "Then came the word of Yahweh unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 18, "ref": "22:18", "o": "בֶּן אָדָ֕ם הָיוּ לִ֥/י בֵֽית יִשְׂרָאֵ֖ל ל/סוג לְ/סִ֑יג כֻּלָּ֡/ם נְ֠חֹשֶׁת וּ/בְדִ֨יל וּ/בַרְזֶ֤ל וְ/עוֹפֶ֨רֶת֙ בְּ/ת֣וֹךְ כּ֔וּר סִגִ֥ים כֶּ֖סֶף הָיֽוּ", "en": {"kjv": "Son of man, the house of Israel is to me become dross: all they are brass, and tin, and iron, and lead, in the midst of the furnace; they are even the dross of silver.", "web": "Son of man, the house of Israel has become dross to me: all of them are brass and tin and iron and lead, in the midst of the furnace; they are the dross of silver.", "bsb": "“Son of man, the house of Israel has become dross to Me. All of them are copper, tin, iron, and lead inside the furnace; they are but the dross of silver.", "asv": "Son of man, the house of Israel is become dross unto me: all of them are brass and tin and iron and lead, in the midst of the furnace; they are the dross of silver.", "ylt": "The house of Israel hath been to Me for dross, All of them are brass, and tin, and iron, and lead, In the midst of a furnace--dross hath silver been,", "dra": "Son of man, the house of Israel is become dross to me: all these are brass, and tin, and iron, and lead, in the midst of the furnace: they are become the dross of silver.", "bbe": "Son of man, the children of Israel have become like the poorest sort of waste metal to me: they are all silver and brass and tin and iron and lead mixed with waste.", "geneva": "Sonne of man, the house of Israel is vnto me as drosse: all they are brasse, and tinne, and yron, and leade in the mids of the fornace: they are euen the drosse of siluer.", "wycliffe": "Thou, sone of man, the hous of Israel is turned to me in to dros, ether filthe of irun; alle these ben bras, and tyn, and irun, and leed, in the myddis of furneis, thei ben maad the dros of siluer.", "rotherham": "Son of man, The house of Israel hath become to me, dross,— They all are copper and tin and iron and lead in the midst of a furnace, The dross of silver, have they become.", "darby": "Son of man, the house of Israel is become dross to me: they are all copper, and tin, and iron, and lead, in the midst of the furnace: they are become the dross of silver.", "twenty": "", "jps": "'Son of man, the house of Israel is become dross unto Me; all of them are brass and tin and iron and lead, in the midst of the furnace; they are the dross of silver.", "acv": "Son of man, the house of Israel has become dross to me. All of them are brass, and tin, and iron, and lead, in the midst of the furnace. They are the dross of silver.", "anderson": "", "haweis": "", "noyes": "Son of man, the house of Israel is become dross to me; all of them are brass, and tin, and iron, and lead, in the midst of the furnace; they are the dross of silver.", "webster": "Son of man, the house of Israel is to me become dross: all they [are] brass, and tin, and iron, and lead, in the midst of the furnace; they are [even] the dross of silver.", "vulgate": "fili hominis versa est mihi domus Israhel in scoriam omnes isti aes et stagnum et ferrum et plumbum in medio fornacis scoria argenti facti sunt;", "brenton": "Son of man, behold, the house of Israel are all become to me as it were mixed with brass, and iron, and tin, and lead; they are mixed up in the midst of the silver."}}, {"v": 19, "ref": "22:19", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֛עַן הֱי֥וֹת כֻּלְּ/כֶ֖ם לְ/סִגִ֑ים לָ/כֵן֙ הִנְ/נִ֣י קֹבֵ֣ץ אֶתְ/כֶ֔ם אֶל תּ֖וֹךְ יְרוּשָׁלִָֽם", "en": {"kjv": "Therefore thus saith the Lord God; Because ye are all become dross, behold, therefore I will gather you into the midst of Jerusalem.", "web": "Therefore thus says the Lord Yahweh: Because you have all become dross, therefore, behold, I will gather you into the midst of Jerusalem.", "bsb": "Therefore this is what the Lord GOD says: ‘Because all of you have become dross, behold, I will gather you into Jerusalem.", "asv": "Therefore thus saith the Lord Jehovah: Because ye are all become dross, therefore, behold, I will gather you into the midst of Jerusalem.", "ylt": "Therefore, thus said the Lord Jehovah: Because of your all becoming dross, Therefore, lo, I am gathering you unto the midst of Jerusalem,", "dra": "Therefore thus saith the Lord God: Because you are all turned into dross, therefore behold I will gather you together in the midst of Jerusalem.", "bbe": "For this cause the Lord has said: Because you have all become waste metal, see, I will get you together inside Jerusalem.", "geneva": "Therefore, thus sayth the Lord God, Because ye are all as drosse, beholde, therefore I will gather you in the middes of Ierusalem.", "wycliffe": "Therfor the Lord God seith these thingis, For that alle ye ben turned in to dros, lo! Y schal gadere you togidere in the myddis of Jerusalem,", "rotherham": "Therefore, Thus, saith My Lord Yahweh, Because ye all are become dross, Therefore, behold me! gathering you into the midst of Jerusalem:", "darby": "Therefore thus saith the Lord Jehovah: Because ye are all become dross, therefore behold, I will gather you into the midst of Jerusalem.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because ye are all become dross, therefore, behold, I will gather you into the midst of Jerusalem.", "acv": "Therefore thus says the lord Jehovah: Because ye have all become dross, therefore, behold, I will gather you into the midst of Jerusalem", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because ye are all of you become dross, therefore, behold, I will gather you into the midst of Jerusalem.", "webster": "Therefore thus saith the Lord GOD, Because ye are all become dross, behold, therefore I will gather you into the midst of Jerusalem.", "vulgate": "propterea haec dicit Dominus Deus eo quod versi estis omnes in scoriam propterea ecce ego congregabo vos in medium Hierusalem;", "brenton": "Therefore say, Thus saith the Lord God; Because ye have become one mixture, therefore I will gather you into the midst of Jerusalem."}}, {"v": 20, "ref": "22:20", "o": "קְבֻ֣צַת כֶּ֡סֶף וּ֠/נְחֹשֶׁת וּ/בַרְזֶ֨ל וְ/עוֹפֶ֤רֶת וּ/בְדִיל֙ אֶל תּ֣וֹךְ כּ֔וּר לָ/פַֽחַת עָלָ֥י/ו אֵ֖שׁ לְ/הַנְתִּ֑יךְ כֵּ֤ן אֶקְבֹּץ֙ בְּ/אַפִּ֣/י וּ/בַ/חֲמָתִ֔/י וְ/הִנַּחְתִּ֥י וְ/הִתַּכְתִּ֖י אֶתְ/כֶֽם", "en": {"kjv": "As they gather silver, and brass, and iron, and lead, and tin, into the midst of the furnace, to blow the fire upon it, to melt it; so will I gather you in mine anger and in my fury, and I will leave you there, and melt you.", "web": "As they gather silver and brass and iron and lead and tin into the midst of the furnace, to blow the fire on it, to melt it; so will I gather you in my anger and in my wrath, and I will lay you there, and melt you.", "bsb": "Just as one gathers silver, copper, iron, lead, and tin into the furnace to melt with a fiery blast, so I will gather you in My anger and wrath, leave you there, and melt you.", "asv": "As they gather silver and brass and iron and lead and tin into the midst of the furnace, to blow the fire upon it, to melt it; so will I gather you in mine anger and in my wrath, and I will lay you there, and melt you.", "ylt": "A gathering of silver, and brass, and iron, and lead, and tin, Unto the midst of a furnace--to blow on it fire, to melt it, So do I gather in Mine anger and in My fury, And I have let rest, and have melted you.", "dra": "As they gather silver, and brass, and tin, and iron, and lead in the midst of the furnace: that I may kindle a fire in it to melt it: so will I gather you together in my fury and in my wrath, and will take my rest, and I will melt you down.", "bbe": "As they put silver and brass and iron and lead and tin together inside the oven, heating up the fire on it to make it soft; so will I get you together in my wrath and in my passion, and, heating the fire with my breath, will make you soft.", "geneva": "As they gather siluer and brasse, and yron, and leade, and tinne into the middes of the fornace, to blowe the fire vpon it to melt it, so wil I gather you in mine anger and in my wrath, and wil put you there and melt you.", "wycliffe": "bi gadering togidere of siluer, and of latoun, and of irun, and of tyn, and of leed, in the myddis of furneis; and Y schal kindle ther ynne a fier, to welle togidere; so Y schal gadere you togidere in my strong veniaunce, and in my wraththe, and Y schal reste. And Y schal welle you togidere,", "rotherham": "As they gather silver and copper and iron and lead and tin into the midst of a furnace, to blow upon it the fire to melt it, So, will I gather in mine anger and in mine indignation, and will let be and will melt you;", "darby": "[As] they gather silver, and copper, and iron, and lead, and tin, into the midst of the furnace, to blow the fire upon it, to melt it, so will I gather you in mine anger and in my fury, and I will lay you on and melt you.", "twenty": "", "jps": "As they gather silver and brass and iron and lead and tin into the midst of the furnace, to blow the fire upon it, to melt it; so will I gather you in Mine anger and in My fury, and I will cast you in, and melt you.", "acv": "as they gather silver and brass and iron and lead and tin into the midst of the furnace, to blow the fire upon it, to melt it. So I will gather you in my anger and in my wrath, and I will lay you there, and melt you.", "anderson": "", "haweis": "", "noyes": "As men gather silver, and brass, and iron, and lead, and tin, into the midst of the furnace, to blow the fire upon it, to melt it, so will I gather you in my anger and in my fury, and I will place you there and melt you.", "webster": "[As] they gather silver, and brass, and iron, and lead, and tin, into the midst of the furnace, to blow the fire upon it, to melt [it]; so will I gather [you] in my anger and in my fury, and I will leave [you there], and melt you.", "vulgate": "congregatione argenti et aeris et ferri et stagni et plumbi in medium fornacis ut succendam in eam ignem ad conflandum sic congregabo in furore meo et in ira mea et requiescam et conflabo vos;", "brenton": "As silver, and brass, and iron, and tin, and lead, are gathered into the midst of the furnace, to blow fire into it, that they may be melted: so will I take you in my wrath, and I will gather and melt you."}}, {"v": 21, "ref": "22:21", "o": "וְ/כִנַּסְתִּ֣י אֶתְ/כֶ֔ם וְ/נָפַחְתִּ֥י עֲלֵי/כֶ֖ם בְּ/אֵ֣שׁ עֶבְרָתִ֑/י וְ/נִתַּכְתֶּ֖ם בְּ/תוֹכָֽ/הּ", "en": {"kjv": "Yea, I will gather you, and blow upon you in the fire of my wrath, and ye shall be melted in the midst thereof.", "web": "Yes, I will gather you, and blow on you with the fire of my wrath, and you shall be melted in its midst.", "bsb": "Yes, I will gather you together and blow on you with the fire of My wrath, and you will be melted within the city.", "asv": "Yea, I will gather you, and blow upon you with the fire of my wrath, and ye shall be melted in the midst thereof.", "ylt": "And I have heaped you up, And blown on you in the fire of My wrath, And ye have been melted in its midst.", "dra": "And will gather you together, and will burn you in the fire of my wrath, and you shall be melted in the midst thereof.", "bbe": "Yes, I will take you, breathing on you the fire of my wrath, and you will become soft in it.", "geneva": "I wil gather you, I say, and blowe the fire of my wrath vpon you, and you shalbe melted in the mids thereof.", "wycliffe": "and Y schal gadere you togidere, and Y schal sette you a fier in the fier of my strong veniaunce, and ye schulen be wellid togidere in the myddis therof.", "rotherham": "Yea I will gather you together, and blow upon you, with the fire of my wrath,— And ye shall be melted in the midst thereof:", "darby": "Yea, I will collect you, and blow upon you the fire of my wrath, and ye shall be melted in the midst thereof.", "twenty": "", "jps": "Yea, I will gather you, and blow upon you with the fire of My wrath, and ye shall be melted in the midst thereof.", "acv": "Yea, I will gather you, and blow upon you with the fire of my wrath, and ye shall be melted in the midst of it.", "anderson": "", "haweis": "", "noyes": "Yea, I will gather you, and blow upon you with the fire of my wrath, and ye shall be melted in the midst thereof.", "webster": "Yes, I will gather you, and blow upon you in the fire of my wrath, and ye shall be melted in the midst of it.", "vulgate": "et congregabo vos et succendam vos in igne furoris mei et conflabimini in medio eius;", "brenton": "And I will blow upon you in the fire of my wrath, and ye shall be melted in the midst thereof."}}, {"v": 22, "ref": "22:22", "o": "כְּ/הִתּ֥וּךְ כֶּ֨סֶף֙ בְּ/ת֣וֹךְ כּ֔וּר כֵּ֖ן תֻּתְּכ֣וּ בְ/תוֹכָ֑/הּ וִֽ/ידַעְתֶּם֙ כִּֽי אֲנִ֣י יְהוָ֔ה שָׁפַ֥כְתִּי חֲמָתִ֖/י עֲלֵי/כֶֽם", "en": {"kjv": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof; and ye shall know that I the Lord have poured out my fury upon you.", "web": "As silver is melted in the midst of the furnace, so you will be melted in its midst; and you will know that I, Yahweh, have poured out my wrath on you.", "bsb": "As silver is melted in a furnace, so you will be melted within the city. Then you will know that I, the LORD, have poured out My wrath upon you.’”", "asv": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof; and ye shall know that I, Jehovah, have poured out my wrath upon you.", "ylt": "As the melting of silver in the midst of a furnace, So are ye melted in its midst, And ye have known that I, Jehovah, I have poured out My fury upon you.'", "dra": "As silver is melted in the midst of the furnace, so shall you be in the midst thereof: and you shall know that I am the Lord, when I have poured out my indignation upon you.", "bbe": "As silver becomes soft in the oven, so you will become soft in it; and you will be certain that I the Lord have let loose my passion on you.", "geneva": "As siluer is melted in the mids of the fornace, so shall ye be melted in the mids thereof, and ye shall knowe, that I the Lord haue powred out my wrath vpon you.", "wycliffe": "As siluer is wellid togidere in the myddis of a furneis, so ye schulen be in the myddis therof; and ye schulen wite, that Y am the Lord, whanne Y haue sched out myn indignacioun on you.", "rotherham": "As silver is melted in he midst of a furnace, So, shall ye be melted in the midst thereof,— Then shall ye know that, I Yahweh, have poured out mine indignation upon you.", "darby": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof: and ye shall know that I Jehovah have poured out my fury upon you.", "twenty": "", "jps": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof; and ye shall know that I HaShem have poured out My fury upon you.'", "acv": "As silver is melted in the midst of the furnace, so ye shall be melted in the midst of it. And ye shall know that I, Jehovah, have poured out my wrath upon you.", "anderson": "", "haweis": "", "noyes": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof; and ye shall know that I, Jehovah, have poured out my fury upon you.", "webster": "As silver is melted in the midst of the furnace, so shall ye be melted in the midst of it; and ye shall know that I the LORD have poured out my fury upon you.", "vulgate": "ut conflatur argentum in medio fornacis sic eritis in medio eius et scietis quia ego Dominus effuderim indignationem meam super vos;", "brenton": "As silver is melted in the midst of a furnace, so shall ye be melted in the midst thereof; and ye shall know that I the Lord have poured out my wrath upon you."}}, {"v": 23, "ref": "22:23", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 24, "ref": "22:24", "o": "בֶּן אָדָ֕ם אֱמָר לָ֕/הּ אַ֣תְּ אֶ֔רֶץ לֹ֥א מְטֹהָרָ֖ה הִ֑יא לֹ֥א גֻשְׁמָ֖/הּ בְּ/י֥וֹם זָֽעַם", "en": {"kjv": "Son of man, say unto her, Thou art the land that is not cleansed, nor rained upon in the day of indignation.", "web": "Son of man, tell her, You are a land that is not cleansed, nor rained on in the day of indignation.", "bsb": "“Son of man, say to her, ‘In the day of indignation, you are a land that has not been cleansed, upon which no rain has fallen.’", "asv": "Son of man, say unto her, Thou art a land that is not cleansed, nor rained upon in the day of indignation.", "ylt": "`Son of man, say to it, Thou art a land, It is not cleansed nor rained on in a day of indignation.", "dra": "Son of man, say to her: Thou art a land that is unclean, and not rained upon in the day of wrath.", "bbe": "Son of man, say to her, You are a land on which no rain or thunderstorm has come in the day of wrath.", "geneva": "Sonne of man, say vnto her; Thou art the land, that is vncleane, and not rained vpon in the day of wrath.", "wycliffe": "and he seide, Sone of man, seie thou to it, Thou art a lond vncleene, and not bireyned in the dai of strong veniaunce.", "rotherham": "Son of man, say to her. Thou, art a land, that is not to be rained upon, nor to receive fruitful showers, in the day of indignation.", "darby": "Son of man, say unto her, Thou art a land that is not cleansed, nor rained upon in the day of indignation.", "twenty": "", "jps": "'Son of man, say unto her: Thou art a land that is not cleansed, nor rained upon in the day of indignation.", "acv": "Son of man, say to her, Thou are a land that is not cleansed, nor rained upon in the day of indignation.", "anderson": "", "haweis": "", "noyes": "Son of man, say to her, Thou art a land that is not cleansed, nor rained upon in the day of indignation.", "webster": "Son of man, say to her, Thou [art] the land that is not cleansed, nor rained upon in the day of indignation.", "vulgate": "fili hominis dic ei tu es terra inmunda et non conpluta in die furoris;", "brenton": "Son of man, say to her, Thou art the land that is not rained upon, neither has rain come upon thee in the day of wrath;"}}, {"v": 25, "ref": "22:25", "o": "קֶ֤שֶׁר נְבִיאֶ֨י/הָ֙ בְּ/תוֹכָ֔/הּ כַּ/אֲרִ֥י שׁוֹאֵ֖ג טֹ֣רֵֽף טָ֑רֶף נֶ֣פֶשׁ אָכָ֗לוּ חֹ֤סֶן וִ/יקָר֙ יִקָּ֔חוּ אַלְמְנוֹתֶ֖י/הָ הִרְבּ֥וּ בְ/תוֹכָֽ/הּ", "en": {"kjv": "There is a conspiracy of her prophets in the midst thereof, like a roaring lion ravening the prey; they have devoured souls; they have taken the treasure and precious things; they have made her many widows in the midst thereof.", "web": "There is a conspiracy of her prophets in its midst, like a roaring lion ravening the prey: they have devoured souls; they take treasure and precious things; they have made her widows many in its midst.", "bsb": "The conspiracy of the princes in her midst is like a roaring lion tearing its prey. They devour the people, seize the treasures and precious things, and multiply the widows within her.", "asv": "There is a conspiracy of her prophets in the midst thereof, like a roaring lion ravening the prey: they have devoured souls; they take treasure and precious things; they have made her widows many in the midst thereof.", "ylt": "A conspiracy of its prophets is in its midst, as a roaring lion tearing prey; The soul they have devoured, Wealth and glory they have taken, Its widows have multiplied in its midst.", "dra": "There is a conspiracy of prophets in the midst thereof: like a lion that roareth and catcheth the prey, they have devoured souls, they have taken riches and hire, they have made many widows in the midst thereof.", "bbe": "Her rulers in her are like a loud-voiced lion violently taking his food; they have made a meal of souls; they have taken wealth and valued property; they have made great the number of widows in her.", "geneva": "There is a conspiracie of her prophets in the mids thereof like a roaring lyon, rauening the praye: they haue deuoured soules: they haue taken the riches and precious things: they haue made her many widowes in the mids thereof.", "wycliffe": "Sweringe togidere, ether conspiringe of profetis is in the myddis therof; as a lioun roringe and takinge prei, thei deuouriden men, thei token richessis and prijs; thei multiplieden widewis therof in the myddis therof.", "rotherham": "Because her princes in her midst are like a roaring lion rending prey,— Life, have they devoured Wealth and precious things, have they been wont to take, Her widows, have they multiplied in her midst.", "darby": "There is a conspiracy of her prophets in the midst of her like a roaring lion ravening the prey; they devour souls; they take away treasure and precious things; they increase her widows in the midst of her;", "twenty": "", "jps": "There is a conspiracy of her prophets in the midst thereof, like a roaring lion ravening the prey; they have devoured souls, they take treasure and precious things, they have made her widows many in the midst thereof.", "acv": "There is a conspiracy by her prophets in the midst of it, like a roaring lion ravening the prey. They have devoured souls. They take treasure and precious things. They have made her widows many in the midst thereof.", "anderson": "", "haweis": "", "noyes": "There is a conspiracy of her prophets in the midst of her; like a roaring lion tearing the prey, they devour the lives of men; they take possession of treasures, and precious things, and make many widows in the midst of her.", "webster": "[There is] a conspiracy of her prophets in the midst of her, like a roaring lion ravening the prey; they have devoured souls; they have taken the treasure and precious things; they have made her many widows in the midst of her.", "vulgate": "coniuratio prophetarum in medio eius sicut leo rugiens capiensque praedam animam devoraverunt opes et pretium acceperunt viduas eius multiplicaverunt in medio illius;", "brenton": "whose princes in the midst of her are as roaring lions seizing prey, devouring souls by oppression, and taking bribes; and thy widows are multiplied in the midst of thee."}}, {"v": 26, "ref": "22:26", "o": "כֹּהֲנֶ֜י/הָ חָמְס֣וּ תוֹרָתִ/י֮ וַ/יְחַלְּל֣וּ קָדָשַׁ/י֒ בֵּֽין קֹ֤דֶשׁ לְ/חֹל֙ לֹ֣א הִבְדִּ֔ילוּ וּ/בֵין הַ/טָּמֵ֥א לְ/טָה֖וֹר לֹ֣א הוֹדִ֑יעוּ וּ/מִ/שַׁבְּתוֹתַ/י֙ הֶעְלִ֣ימוּ עֵֽינֵי/הֶ֔ם וָ/אֵחַ֖ל בְּ/תוֹכָֽ/ם", "en": {"kjv": "Her priests have violated my law, and have profaned mine holy things: they have put no difference between the holy and profane, neither have they shewed difference between the unclean and the clean, and have hid their eyes from my sabbaths, and I am profaned among them.", "web": "Her priests have done violence to my law, and have profaned my holy things: they have made no distinction between the holy and the common, neither have they caused men to discern between the unclean and the clean, and have hidden their eyes from my Sabbaths, and I am profaned among them.", "bsb": "Her priests do violence to My law and profane My holy things. They make no distinction between the holy and the common, and they fail to distinguish between the clean and the unclean. They disregard My Sabbaths, so that I am profaned among them.", "asv": "Her priests have done violence to my law, and have profaned my holy things: they have made no distinction between the holy and the common, neither have they caused men to discern between the unclean and the clean, and have hid their eyes from my sabbaths, and I am profaned among them.", "ylt": "Its priests have wronged My law, And they pollute My holy things, Between holy and common they have not made separation, And between the unclean and the clean they have not made known, And from my sabbaths they have hidden their eyes, And I am pierced in their midst.", "dra": "Her priests have despised my law, and have defiled my sanctuaries: they have put no difference between holy and profane: nor have distinguished between the polluted and the clean: and they have turned away their eyes from my sabbaths, and I was profaned in the midst of them.", "bbe": "Her priests have been acting violently against my law; they have made my holy things unclean: they have made no division between what is holy and what is common, and they have not made it clear that the unclean is different from the clean, and their eyes have been shut to my Sabbaths, and I am not honoured among them.", "geneva": "Her Priests haue broken my Lawe, and haue defiled mine holy things: they haue put no difference betweene the holy and prophane, neither discerned betweene the vncleane, and the cleane, and haue hid their eyes from my Sabbaths, and I am prophaned among them.", "wycliffe": "Preestis therof dispisiden my lawe, and defouliden my seyntuaries; thei hadden not difference bitwixe hooli thing and vnhooli, thei vndurstoden not bitwixe defoulid thing and cleene thing; and thei turneden awei her iyen fro my sabatis, and Y was defoulid in the myddis of hem.", "rotherham": "Her priests have done violence to my law And have profaned my holy things, Between the hallowed and the common, have they put no difference, And between the unclean and clean, have they not taught men to discern,- And from my sabbaths, have they hid their eyes, So that I have been profaned in their midst.", "darby": "her priests do violence to my law, and profane my holy things: they put no difference between the holy and profane, neither do they make known [the difference] between the unclean and the clean, and they hide their eyes from my sabbaths, and I am profaned among them.", "twenty": "", "jps": "Her priests have done violence to My law, and have profaned My holy things; they have put no difference between the holy and the common, neither have they taught difference between the unclean and the clean, and have hid their eyes from My sabbaths, and I am profaned among them.", "acv": "Her priests have done violence to my law, and have profaned my holy things. They have made no distinction between the holy and the common, nor have they caused men to discern between the unclean and the clean, and have hid their eyes from my sabbaths, and I am profaned among them.", "anderson": "", "haweis": "", "noyes": "Her priests violate my law, and profane my holy things. They make no distinction between the holy and profane, and show not the difference between the clean and the unclean; and they hide their eyes from my sabbaths, and I am profaned among them.", "webster": "Her priests have violated my law, and have profaned my holy things: they have put no difference between the holy and profane, neither have they shown [difference] between the unclean and the clean, and have hid their eyes from my sabbaths, and I am profaned among them.", "vulgate": "sacerdotes eius contempserunt legem meam et polluerunt sanctuaria mea inter sanctum et profanum non habuere distantiam et inter pollutum et mundum non intellexerunt et a sabbatis meis averterunt oculos suos et coinquinabar in medio eorum;", "brenton": "Her priests also have set at nought my law, and profaned my holy things: they have not distinguished between the holy and profane, nor have they distinguished between the unclean and the clean, and have hid their eyes from my sabbaths, and I was profaned in the midst of them."}}, {"v": 27, "ref": "22:27", "o": "שָׂרֶ֣י/הָ בְ/קִרְבָּ֔/הּ כִּ/זְאֵבִ֖ים טֹ֣רְפֵי טָ֑רֶף לִ/שְׁפָּךְ דָּם֙ לְ/אַבֵּ֣ד נְפָשׁ֔וֹת לְמַ֖עַן בְּצֹ֥עַ בָּֽצַע", "en": {"kjv": "Her princes in the midst thereof are like wolves ravening the prey, to shed blood, and to destroy souls, to get dishonest gain.", "web": "Her princes in its midst are like wolves ravening the prey, to shed blood, and to destroy souls, that they may get dishonest gain.", "bsb": "Her officials within her are like wolves tearing their prey, shedding blood, and destroying lives for dishonest gain.", "asv": "Her princes in the midst thereof are like wolves ravening the prey, to shed blood, and to destroy souls, that they may get dishonest gain.", "ylt": "Its princes in its midst are as wolves, Tearing prey, to shed blood, to destroy souls, For the sake of gaining dishonest gain.", "dra": "Her princes in the midst of her, are like wolves ravening the prey to shed blood, and to destroy souls, and to run after gains through covetousness.", "bbe": "Her rulers in her are like wolves violently taking their food; putting men to death and causing the destruction of souls, so that they may get their profit.", "geneva": "Her princes in the mids thereof are like wolues, rauening the praye to shed blood, and to destroy soules for their owne couetous lucre.", "wycliffe": "The princes therof in the myddis therof weren as wolues rauyschinge prey, to schede out blood, and to leese men, and in suynge lucris gredili.", "rotherham": "Her rulers within her have been like wolves, rending prey,- In shedding blood In destroying lives, For the sake of getting dishonest gain.", "darby": "Her princes in the midst of her are like wolves ravening the prey, to shed blood, to destroy souls, to get dishonest gain.", "twenty": "", "jps": "Her princes in the midst thereof are like wolves ravening the prey: to shed blood, and to destroy souls, so as to get dishonest gain.", "acv": "Her rulers in the midst of it are like wolves ravening the prey, to shed blood, to destroy souls, that they may get dishonest gain.", "anderson": "", "haweis": "", "noyes": "Her princes in the midst of her are like wolves tearing the prey. They shed blood, they destroy life, that they may get gain.", "webster": "Her princes in the midst of her [are] like wolves ravening the prey, to shed blood, [and] to destroy souls, to get dishonest gain.", "vulgate": "principes eius in medio illius quasi lupi rapientes praedam ad effundendum sanguinem et perdendas animas et avare sectanda lucra;", "brenton": "Her princes in the midst of her are as wolves ravening to shed blood, that they may get dishonest gain."}}, {"v": 28, "ref": "22:28", "o": "וּ/נְבִיאֶ֗י/הָ טָח֤וּ לָ/הֶם֙ תָּפֵ֔ל חֹזִ֣ים שָׁ֔וְא וְ/קֹסְמִ֥ים לָ/הֶ֖ם כָּזָ֑ב אֹמְרִ֗ים כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה וַֽ/יהוָ֖ה לֹ֥א דִבֵּֽר", "en": {"kjv": "And her prophets have daubed them with untempered morter, seeing vanity, and divining lies unto them, saying, Thus saith the Lord God, when the Lord hath not spoken.", "web": "Her prophets have plastered for them with whitewash, seeing false visions, and divining lies to them, saying, Thus says the Lord Yahweh, when Yahweh has not spoken.", "bsb": "Her prophets whitewash these deeds by false visions and lying divinations, saying, ‘This is what the Lord GOD says,’ when the LORD has not spoken.", "asv": "And her prophets have daubed for them with untempered mortar, seeing false visions, and divining lies unto them, saying, Thus saith the Lord Jehovah, when Jehovah hath not spoken.", "ylt": "And its prophets have daubed for them with chalk, Seeing a vain thing, and divining for them a lie, Saying, `Thus said the Lord Jehovah:' And Jehovah hath not spoken.", "dra": "And her prophets have daubed them without tempering the mortar, seeing vain things, and divining lies unto them, saying: Thus saith the Lord God: when the Lord hath not spoken.", "bbe": "And her prophets have been using whitewash, seeing foolish visions and making false use of secret arts, saying, This is what the Lord has said, when the Lord has said nothing.", "geneva": "And her prophets haue dawbed them with vntempered morter, seeing vanities, and diuining lies vnto them, saying, Thus sayth the Lord God, when the Lord had not spoken.", "wycliffe": "Forsothe the profetis therof pargetiden hem with out temperure, and seyen veyn thingis, and dyuyneden leesingis to hem, and seiden, The Lord God seith these thingis, whanne the Lord spak not.", "rotherham": "And her prophets have coated it for them with whitewash, Seeing visions of falsehood And divining for them lies, Saying, Thus saith My Lord Yahweh, when Yahweh, hath not spoken.", "darby": "And her prophets have daubed for them with untempered [mortar], seeing vanity and divining lies unto them, saying, Thus saith the Lord Jehovah! and Jehovah hath not spoken.", "twenty": "", "jps": "And her prophets have daubed for them with whited plaster, seeing falsehood, and divining lies unto them, saying: Thus saith the L-rd GOD, when HaShem hath not spoken.", "acv": "And her prophets have daubed for them with untempered mortar, seeing false visions, and divining lies to them, saying, Thus says the lord Jehovah, when Jehovah has not spoken.", "anderson": "", "haweis": "", "noyes": "Her prophets daub for them with untempered mortar, seeing falsehood, and divining to them, saying, \"Thus saith the Lord Jehovah,\" when Jehovah hath not spoken.", "webster": "And her prophets have daubed them with untempered [mortar], seeing vanity, and divining lies to them, saying, Thus saith the Lord GOD, when the LORD hath not spoken.", "vulgate": "prophetae autem eius liniebant eos absque temperamento videntes vana et divinantes eis mendacium dicentes haec dicit Dominus Deus cum Dominus non sit locutus;", "brenton": "And her prophets that daub them shall fall, that see vanities, that prophesy falsehoods, saying, Thus saith the Lord, when the Lord has not spoken."}}, {"v": 29, "ref": "22:29", "o": "עַ֤ם הָ/אָ֨רֶץ֙ עָ֣שְׁקוּ עֹ֔שֶׁק וְ/גָזְל֖וּ גָּזֵ֑ל וְ/עָנִ֤י וְ/אֶבְיוֹן֙ הוֹנ֔וּ וְ/אֶת הַ/גֵּ֥ר עָשְׁק֖וּ בְּ/לֹ֥א מִשְׁפָּֽט", "en": {"kjv": "The people of the land have used oppression, and exercised robbery, and have vexed the poor and needy: yea, they have oppressed the stranger wrongfully.", "web": "The people of the land have used oppression, and exercised robbery; yes, they have troubled the poor and needy, and have oppressed the foreigner wrongfully.", "bsb": "The people of the land have practiced extortion and committed robbery. They have oppressed the poor and needy and have exploited the foreign resident without justice.", "asv": "The people of the land have used oppression, and exercised robbery; yea, they have vexed the poor and needy, and have oppressed the sojourner wrongfully.", "ylt": "The people of the land have used oppression, And have taken plunder violently away, And humble and needy have oppressed, And the sojourner oppressed--without judgment.", "dra": "The people of the land have used oppression, and committed robbery: they afflicted the needy and poor, and they oppressed the stranger by calumny without judgment.", "bbe": "The people of the land have been acting cruelly, taking men's goods by force; they have been hard on the poor and those in need, and have done wrong to the man from a strange land.", "geneva": "The people of the land haue violently oppressed by spoyling and robbing, and haue vexed the poore and the needy: yea, they haue oppressed the stranger against right.", "wycliffe": "The puples of the lond calengiden fals caleng, and rauyschiden bi violence; thei turmentiden a nedi man and pore, and oppressiden a comeling bi fals caleng, with out doom.", "rotherham": "The people of the land have exacted oppression, and seized plunder,- Even the afflicted and the needy, have they maltreated, And the sojourner have they oppressed without justice.", "darby": "The people of the land use oppression and practise robbery; and they vex the poor and needy, and oppress the stranger wrongfully.", "twenty": "", "jps": "The people of the land have used oppression, and exercised robbery, and have wronged the poor and needy, and have oppressed the stranger unlawfully.", "acv": "The people of the land have used oppression, and exercised robbery. Yea, they have vexed the poor and needy man, and have oppressed the sojourner wrongfully.", "anderson": "", "haweis": "", "noyes": "The people of the land are guilty of oppression, and practise robbery, and distress the poor and needy; yea, they oppress the stranger, and have no justice.", "webster": "The people of the land have used oppression, and exercised robbery, and have oppressed the poor and needy: yes, they have oppressed the stranger wrongfully.", "vulgate": "populi terrae calumniabantur calumniam et rapiebant violenter egenum et pauperem adfligebant et advenam opprimebant calumnia absque iudicio;", "brenton": "That sorely oppress the people of the land with injustice, and commit robbery; oppressing the poor and needy, and not dealing justly with the stranger."}}, {"v": 30, "ref": "22:30", "o": "וָ/אֲבַקֵּ֣שׁ מֵ/הֶ֡ם אִ֣ישׁ גֹּֽדֵר גָּדֵר֩ וְ/עֹמֵ֨ד בַּ/פֶּ֧רֶץ לְ/פָנַ֛/י בְּעַ֥ד הָ/אָ֖רֶץ לְ/בִלְתִּ֣י שַׁחֲתָ֑/הּ וְ/לֹ֖א מָצָֽאתִי", "en": {"kjv": "And I sought for a man among them, that should make up the hedge, and stand in the gap before me for the land, that I should not destroy it: but I found none.", "web": "I sought for a man among them, who should build up the wall, and stand in the gap before me for the land, that I should not destroy it; but I found no one.", "bsb": "I searched for a man among them to repair the wall and stand in the gap before Me on behalf of the land, so that I should not destroy it. But I found no one.", "asv": "And I sought for a man among them, that should build up the wall, and stand in the gap before me for the land, that I should not destroy it; but I found none.", "ylt": "And I seek of them a man making a fence, And standing in the breach before Me, In behalf of the land--not to destroy it, And I have not found.", "dra": "And I sought among them for a man that might set up a hedge, and stand in the gap before me in favour of the land, that I might not destroy it: and I found none.", "bbe": "And I was looking for a man among them who would make up the wall and take his station in the broken place before me for the land, so that I might not send destruction on it: but there was no one.", "geneva": "And I sought for a man among them, that should make vp the hedge, and stand in the gap before me for the land, that I should not destroy it, but I found none.", "wycliffe": "And Y souyte of hem a man, that schulde sette an hegge bitwixe, and stonde set ayens me for the lond, that Y schulde not distrie it, and Y foond not.", "rotherham": "Then sought I from among them, a man Who could build up a wall And stand in the breach before me in behalf of the land So that I might not destroy her,— But I found none.", "darby": "And I sought for a man among them, that should make up the fence, and stand in the breach before me for the land, that I should not destroy it; but I found none.", "twenty": "", "jps": "And I sought for a man among them, that should make up the hedge, and stand in the breach before Me for the land, that I should not destroy it; but I found none.", "acv": "And I sought for a man among them who should build up the wall, and stand in the gap before me for the land, that I should not destroy it, but I found none.", "anderson": "", "haweis": "", "noyes": "I have sought for a man among them that should make a wall, and stand in the gap before me for the land, that I might not destroy it; but I found none.", "webster": "And I sought for a man among them, that should make up the hedge, and stand in the gap before me for the land, that I should not destroy it: but I found none.", "vulgate": "et quaesivi de eis virum qui interponeret sepem et staret oppositus contra me pro terra ne dissiparem eam et non inveni;", "brenton": "And I sought from among them a man behaving uprightly, and standing before me perfectly in the time of wrath, so that I should not utterly destroy her: but I found him not."}}, {"v": 31, "ref": "22:31", "o": "וָ/אֶשְׁפֹּ֤ךְ עֲלֵי/הֶם֙ זַעְמִ֔/י בְּ/אֵ֥שׁ עֶבְרָתִ֖/י כִּלִּיתִ֑י/ם דַּרְכָּ/ם֙ בְּ/רֹאשָׁ֣/ם נָתַ֔תִּי נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "Therefore have I poured out mine indignation upon them; I have consumed them with the fire of my wrath: their own way have I recompensed upon their heads, saith the Lord God.", "web": "Therefore have I poured out my indignation on them; I have consumed them with the fire of my wrath: their own way have I brought on their heads, says the Lord Yahweh.", "bsb": "So I have poured out My indignation upon them and consumed them with the fire of My fury. I have brought their ways down upon their own heads, declares the Lord GOD.”", "asv": "Therefore have I poured out mine indignation upon them; I have consumed them with the fire of my wrath: their own way have I brought upon their heads, saith the Lord Jehovah.", "ylt": "And I pour out on them mine indignation, By fire of My wrath I have consumed them, Their way on their own head I have put, An affirmation of the Lord Jehovah!'", "dra": "And I poured out my indignation upon them, in the fire of my wrath I consumed them: I have rendered their way upon their own head, saith the Lord God.", "bbe": "And I let loose my passion on them, and have put an end to them in the fire of my wrath: I have made the punishment of their ways come on their heads, says the Lord.", "geneva": "Therefore haue I powred out mine indignation vpon them, and consumed them with the fire of my wrath: their owne wayes haue I rendred vpon their heads, sayth the Lord God.", "wycliffe": "And Y schedde out on hem myn indignacioun, and Y wastide hem in the fier of my wraththe; Y yeldide the weie of hem on the heed of hem, seith the Lord God.", "rotherham": "Therefore have I poured out upon them mine indignation, In the fire of mine outburst, have I consumed them,— Their way, upon their own head, have I placed Declareth, My Lord Yahweh.", "darby": "And I will pour out mine indignation upon them; I will consume them in the fire of my wrath: their own way will I recompense upon their head, saith the Lord Jehovah.", "twenty": "", "jps": "Therefore have I poured out Mine indignation upon them; I have consumed them with the fire of My wrath; their own way have I brought upon their heads, saith the L-rd GOD.'", "acv": "Therefore I have poured out my indignation upon them. I have consumed them with the fire of my wrath. I have brought their own way upon their heads, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Therefore will I pour out my indignation upon them; I will consume them with the fire of my wrath; I will bring their way upon their heads, saith the Lord Jehovah.", "webster": "Therefore have I poured out my indignation upon them; I have consumed them with the fire of my wrath: their own way have I recompensed upon their heads, saith the Lord GOD.", "vulgate": "et effudi super eos indignationem meam in igne irae meae consumpsi eos viam eorum in caput eorum reddidi ait Dominus Deus;", "brenton": "So I have poured out my wrath upon her in the fury of mine anger, to accomplish it. I have recompensed their ways on their own heads, saith the Lord God."}}]}, {"c": 23, "verses": [{"v": 1, "ref": "23:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came again to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "The word of Jehovah came again unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying, `Son of man,", "dra": "And the word of the Lord came to me, saying:", "bbe": "The word of the Lord came to me again, saying,", "geneva": "The worde of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying,", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came again to me, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came to me again, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "23:2", "o": "בֶּן אָדָ֑ם שְׁתַּ֣יִם נָשִׁ֔ים בְּנ֥וֹת אֵם אַחַ֖ת הָיֽוּ", "en": {"kjv": "Son of man, there were two women, the daughters of one mother:", "web": "Son of man, there were two women, the daughters of one mother:", "bsb": "“Son of man, there were two women, daughters of the same mother,", "asv": "Son of man, there were two women, the daughters of one mother:", "ylt": "Two women were daughters of one mother,", "dra": "Son of man, there were two women, daughters of one mother.", "bbe": "Son of man, there were two women, daughters of one mother:", "geneva": "Sonne of man, there were two women, the daughters of one mother.", "wycliffe": "and he seide, Thou, sone of man, twei wymmen weren the douytris of o modir, and diden fornycacioun in Egipt;", "rotherham": "Son of man, Two women, daughters of one mother, there were;", "darby": "Son of man, there were two women, daughters of one mother.", "twenty": "", "jps": "'Son of man, there were two women, the daughters of one mother;", "acv": "Son of man, there were two women, the daughters of one mother.", "anderson": "", "haweis": "", "noyes": "Son of man, there were two women, daughters of one mother;", "webster": "Son of man, there were two women, the daughters of one mother:", "vulgate": "fili hominis duae mulieres filiae matris unius fuerunt;", "brenton": "Son of man, there were two women, daughters of one mother:"}}, {"v": 3, "ref": "23:3", "o": "וַ/תִּזְנֶ֣ינָה בְ/מִצְרַ֔יִם בִּ/נְעוּרֵי/הֶ֖ן זָנ֑וּ שָׁ֚מָּ/ה מֹעֲכ֣וּ שְׁדֵי/הֶ֔ן וְ/שָׁ֣ם עִשּׂ֔וּ דַּדֵּ֖י בְּתוּלֵי/הֶֽן", "en": {"kjv": "And they committed whoredoms in Egypt; they committed whoredoms in their youth: there were their breasts pressed, and there they bruised the teats of their virginity.", "web": "and they played the prostitute in Egypt; they played the prostitute in their youth; there were their breasts pressed, and there was handled the bosom of their virginity.", "bsb": "and they played in Egypt, prostituting themselves from their youth. Their breasts were fondled there, and their virgin bosoms caressed.", "asv": "and they played the harlot in Egypt; they played the harlot in their youth; there were their breasts pressed, and there was handled the bosom of their virginity.", "ylt": "And they go a-whoring in Egypt, In their youth they have gone a-whoring, There they have bruised their breasts, And there they have dealt with the loves of their virginity.", "dra": "And they committed fornication in Egypt, in their youth they committed fornication: there were their breasts pressed down, and the teats of their virginity were bruised.", "bbe": "They were acting like loose women in Egypt; when they were young their behaviour was loose: there their breasts were crushed, even the points of their young breasts were crushed.", "geneva": "And they committed fornication in Egypt, they committed fornication in their youth: there were their breasts pressed, and there they bruised the teates of their virginitie.", "wycliffe": "in her yonge wexynge age thei diden fornicacioun; there the brestis of hem weren maad low, and the tetis of the tyme of mariage of hem weren brokun.", "rotherham": "And they became unchaste in Egypt, In their youth, became they unchaste, There, were handled their breasts, And there, were pressed their virgin bosoms.", "darby": "And they committed whoredom in Egypt; they committed whoredom in their youth: there were their breasts pressed, and there were handled the teats of their virginity.", "twenty": "", "jps": "and they committed harlotries in Egypt; they committed harlotries in their youth; there were their bosoms pressed, and there their virgin breasts were bruised.", "acv": "And they played the harlot in Egypt. They played the harlot in their youth. There their breasts were pressed, and there was handled the bosom of their virginity.", "anderson": "", "haweis": "", "noyes": "and they committed fornication in Egypt; in their youth they committed fornication. There they allowed their breasts to be pressed, and their virgin teats to be handled.", "webster": "And they committed lewd deeds in Egypt; they committed lewd deeds in their youth: there were their breasts pressed, and there they were first corrupted.", "vulgate": "et fornicatae sunt in Aegypto in adulescentia sua fornicatae sunt ibi subacta sunt ubera earum et fractae sunt mammae pubertatis earum;", "brenton": "and they went a-whoring in Egypt in their youth: there their breasts fell, there they lost their virginity."}}, {"v": 4, "ref": "23:4", "o": "וּ/שְׁמוֹתָ֗/ן אָהֳלָ֤ה הַ/גְּדוֹלָה֙ וְ/אָהֳלִיבָ֣ה אֲחוֹתָ֔/הּ וַ/תִּֽהְיֶ֣ינָה לִ֔/י וַ/תֵּלַ֖דְנָה בָּנִ֣ים וּ/בָנ֑וֹת וּ/שְׁמוֹתָ֕/ן שֹׁמְר֣וֹן אָהֳלָ֔ה וִ/ירוּשָׁלִַ֖ם אָהֳלִיבָֽה", "en": {"kjv": "And the names of them were Aholah the elder, and Aholibah her sister: and they were mine, and they bare sons and daughters. Thus were their names; Samaria is Aholah, and Jerusalem Aholibah.", "web": "Their names were Oholah the elder, and Oholibah her sister: and they became mine, and they bore sons and daughters. As for their names, Samaria is Oholah, and Jerusalem Oholibah.", "bsb": "The older was named Oholah, and her sister was named Oholibah. They became Mine and gave birth to sons and daughters. As for their identities, Oholah is Samaria, and Oholibah is Jerusalem.", "asv": "And the names of them were Oholah the elder, and Oholibah her sister: and they became mine, and they bare sons and daughters. And as for their names, Samaria is Oholah, and Jerusalem Oholibah.", "ylt": "And their names are Aholah the elder, And Aholibah her sister, And they are Mine, and bear sons and daughters. As to their names--Samaria is Aholah, And Jerusalem is Aholibah.", "dra": "And their names were Oolla the elder, and Ooliba her younger sister: and I took them, and they bore sons and daughters. Now for their names, Samaria is Oolla, and Jerusalem is Ooliba.", "bbe": "Their names were Oholah, the older, and Oholibah, her sister: and they became mine, and gave birth to sons and daughters. As for their names, Samaria is Oholah, and Jerusalem, Oholibah.", "geneva": "And the names of them were Aholah the elder, and Aholibah her sister: and they were mine, and they bare sonnes and daughters: thus were their names. Samaria is Aholah, and Ierusalem Aholibah.", "wycliffe": "Forsothe the names of hem ben, Oolla, the more sistir, and Ooliba the lesse sistir of hir. And Y hadde hem, and thei childiden sones and douytris; certis the names of hem ben Samarie Oolla, and Jerusalem Ooliba.", "rotherham": "And their names were Oholah the elder And Oholibah—her sister, And they became mine and bare sons and daughters,- And as for their names, Samaria was Oholah, And Jerusalem, was Oholibah.", "darby": "And their names were Oholah the elder, and Oholibah her sister; and they were mine, and they bore sons and daughters. As for their names: Samaria is Oholah, and Jerusalem Oholibah.", "twenty": "", "jps": "And the names of them were Oholah the elder, and Oholibah her sister; and they became Mine, and they bore sons and daughters. And as for their names, Samaria is Oholah, and Jerusalem Oholibah.", "acv": "And the names of them were Oholah the elder, and Oholibah her sister. And they became mine, and they bore sons and daughters. And as for their names, Samaria is Oholah, and Jerusalem Oholibah.", "anderson": "", "haweis": "", "noyes": "Their names were Aholah, the elder, and Aholibah, her sister; and they became mine, and bore sons and daughters; as to their names, moreover, Aholah is Samaria, and Aholibah, Jerusalem.", "webster": "And the names of them [were] Aholah the elder, and Aholibah her sister: and they were mine, and they bore sons and daughters. Thus [were] their names; Samaria [is] Aholah, and Jerusalem Aholibah.", "vulgate": "nomina autem earum Oolla maior et Ooliba soror eius et habui eas et pepererunt filios et filias porro earum nomina Samaria Oolla et Hierusalem Ooliba;", "brenton": "And their names were Oola the elder, and Ooliba her sister: and they were mine, and bore sons and daughters: and as for their names, Samaria was Oola, and Jerusalem was Ooliba."}}, {"v": 5, "ref": "23:5", "o": "וַ/תִּ֥זֶן אָהֳלָ֖ה תַּחְתָּ֑/י וַ/תַּעְגַּב֙ עַֽל מְאַהֲבֶ֔י/הָ אֶל אַשּׁ֖וּר קְרוֹבִֽים", "en": {"kjv": "And Aholah played the harlot when she was mine; and she doted on her lovers, on the Assyrians her neighbours,", "web": "Oholah played the prostitute when she was mine; and she doted on her lovers, on the Assyrians her neighbors,", "bsb": "Oholah prostituted herself while she was still Mine. She lusted after her lovers, the Assyrians—warriors", "asv": "And Oholah played the harlot when she was mine; and she doted on her lovers, on the Assyrians her neighbors,", "ylt": "And go a-whoring doth Aholah under Me, And she doteth on her lovers, On the neighbouring Assyrians,", "dra": "And Oolla committed fornication against me, and doted on her lovers, on the Assyrians that came to her,", "bbe": "And Oholah was untrue to me when she was mine; she was full of desire for her lovers, even for the Assyrians, her neighbours,", "geneva": "And Aholah played the harlot when she was mine, and she was set on fire with her louers, to wit, with the Assyrians her neighbours,", "wycliffe": "Therfor Oolla dide fornicacioun on me, and was wood on hir louyeris, on Assiriens neiyinge,", "rotherham": "Then became Oholah unchaste after she had become mine- And lusted after her lovers, For Assyrians, so warlike,", "darby": "And Oholah played the harlot when she was mine; and she lusted after her lovers, after the Assyrians [her] neighbours,", "twenty": "", "jps": "And Oholah played the harlot when she was Mine; and she doted on her lovers, on the Assyrians, warriors,", "acv": "And Oholah played the harlot when she was mine, and she doted on her lovers, on the Assyrians her neighbors,", "anderson": "", "haweis": "", "noyes": "And Aholah played the harlot when she was mine; and she doted on her lovers, on the Assyrians, her neighbors", "webster": "And Aholah played the harlot when she was mine; and she doted on her lovers, on the Assyrians [her] neighbors.", "vulgate": "fornicata est igitur Oolla super me et insanivit in amatores suos in Assyrios propinquantes;", "brenton": "And Oola went a-whoring from me, and doted on her lovers, on the Assyrians that were her neighbors,"}}, {"v": 6, "ref": "23:6", "o": "לְבֻשֵׁ֤י תְכֵ֨לֶת֙ פַּח֣וֹת וּ/סְגָנִ֔ים בַּח֥וּרֵי חֶ֖מֶד כֻּלָּ֑/ם פָּרָשִׁ֕ים רֹכְבֵ֖י סוּסִֽים", "en": {"kjv": "Which were clothed with blue, captains and rulers, all of them desirable young men, horsemen riding upon horses.", "web": "who were clothed with blue, governors and rulers, all of them desirable young men, horsemen riding on horses.", "bsb": "clothed in blue, governors and commanders, all desirable young men, horsemen mounted on steeds.", "asv": "who were clothed with blue, governors and rulers, all of them desirable young men, horsemen riding upon horses.", "ylt": "Clothed with blue--governors and prefects, Desirable young men all of them, Horsemen, riding on horses,", "dra": "Who were clothed with blue, princes, and rulers, beautiful youths, all horsemen, mounted upon horses.", "bbe": "Who were clothed in blue, captains and rulers, all of them young men to be desired, horsemen seated on horses.", "geneva": "Which were clothed with blewe silke, both captaines and princes: they were all pleasant yong men, and horsemen riding vpon horses.", "wycliffe": "clothid with iacinct, princes, and magistratis, yonge men of coueytise, alle kniytis, and stieris of horsis.", "rotherham": "Clothed in blue Governors and deputies, Attractive young men all of them,-Horsemen riding on horses.", "darby": "clothed with blue, governors and rulers, all of them attractive young men, horsemen riding upon horses.", "twenty": "", "jps": "clothed with blue, governors and rulers, handsome young men all of them, horsemen riding upon horses.", "acv": "who were clothed with blue, governors and rulers, all of them desirable young men, horsemen riding upon horses.", "anderson": "", "haweis": "", "noyes": "who were clothed with blue, captains and rulers, all of them desirable young men, horsemen, riding on horses.", "webster": "[Who were] clothed with blue, captains and rulers, all of them desirable young men, horsemen riding upon horses.", "vulgate": "vestitos hyacintho principes et magistratus iuvenes cupidinis universos equites ascensores equorum;", "brenton": "clothed with purple, princes and captains; they were young men and choice, all horseman riding on horses."}}, {"v": 7, "ref": "23:7", "o": "וַ/תִּתֵּ֤ן תַּזְנוּתֶ֨י/הָ֙ עֲלֵי/הֶ֔ם מִבְחַ֥ר בְּנֵֽי אַשּׁ֖וּר כֻּלָּ֑/ם וּ/בְ/כֹ֧ל אֲשֶׁר עָֽגְבָ֛ה בְּ/כָל גִּלּוּלֵי/הֶ֖ם נִטְמָֽאָה", "en": {"kjv": "Thus she committed her whoredoms with them, with all them that were the chosen men of Assyria, and with all on whom she doted: with all their idols she defiled herself.", "web": "She bestowed her prostitution on them, the choicest men of Assyria all of them; and on whoever she doted, with all their idols she defiled herself.", "bsb": "She offered sexual favors to all the elite of Assyria. She defiled herself with all the idols of those for whom she lusted.", "asv": "And she bestowed her whoredoms upon them, the choicest men of Assyria all of them; and on whomsoever she doted, with all their idols she defiled herself.", "ylt": "And she giveth her whoredoms on them, The choice of the sons of Asshur, All of them--even all on whom she doted, By all their idols she hath been defiled.", "dra": "And she committed her fornications with those chosen men, all sons of the Assyrians: and she defiled herself with the uncleanness of all them on whom she doted.", "bbe": "And she gave her unclean love to them, all of them the noblest men of Assyria: and she made herself unclean with the images of all who were desired by her.", "geneva": "Thus she committed her whoredome with them, euen with all them that were the chosen men of Asshur, and with all on whome she doted, and defiled her selfe with all their idoles.", "wycliffe": "And sche yaf hir fornicaciouns on hem, on alle the chosun sones of Assiriens; and in alle on whiche sche was wood, sche was defoulid in the vnclennessis of hem.", "rotherham": "So she bestowed her unchastities upon them, The choicest men of Assyria all of them,- And, with whomsoever she lusted after-with all their manufactured gods, she defiled herself.", "darby": "And she bestowed her whoredoms upon them, all of them the choice of the children of Asshur; and with all after whom she lusted, with all their idols she defiled herself.", "twenty": "", "jps": "And she bestowed her harlotries upon them, the choicest men of Assyria all of them; and on whomsoever she doted, with all their idols she defiled herself.", "acv": "And she bestowed her whoredoms upon them, the choicest men of Assyria all of them. And on whomever she doted, with all their idols she defiled herself.", "anderson": "", "haweis": "", "noyes": "Thus she committed fornication with them, with all the choice young men of Assyria, and with all on whom she doted; with all their idols she defiled herself.", "webster": "Thus she committed her lewd deeds with them, with all them [that were] the chosen men of Assyria, and with all on whom she doted: with all their idols she defiled herself.", "vulgate": "et dedit fornicationes suas super eos electos filios Assyriorum universos et in omnibus in quos insanivit in inmunditiis eorum polluta est;", "brenton": "And she bestowed her fornication upon them; all were choice sons of the Assyrians: and on whomsoever she doted herself, with them she defiled herself in all their devices."}}, {"v": 8, "ref": "23:8", "o": "וְ/אֶת תַּזְנוּתֶ֤י/הָ מִ/מִּצְרַ֨יִם֙ לֹ֣א עָזָ֔בָה כִּ֤י אוֹתָ/הּ֙ שָׁכְב֣וּ בִ/נְעוּרֶ֔י/הָ וְ/הֵ֥מָּה עִשּׂ֖וּ דַּדֵּ֣י בְתוּלֶ֑י/הָ וַ/יִּשְׁפְּכ֥וּ תַזְנוּתָ֖/ם עָלֶֽי/הָ", "en": {"kjv": "Neither left she her whoredoms brought from Egypt: for in her youth they lay with her, and they bruised the breasts of her virginity, and poured their whoredom upon her.", "web": "Neither has she left her prostitution since leaving Egypt; for in her youth they lay with her, and they handled the bosom of her virginity; and they poured out their prostitution on her.", "bsb": "She did not give up the prostitution she began in Egypt, when men slept with her in her youth, caressed her virgin bosom, and poured out their lust upon her.", "asv": "Neither hath she left her whoredoms since the days of Egypt; for in her youth they lay with her, and they handled the bosom of her virginity; and they poured out their whoredom upon her.", "ylt": "And her whoredoms out of Egypt she hath not forsaken, For with her they lay in her youth, And they dealt with the loves of her virginity, And they pour out their whoredoms on her.", "dra": "Moreover also she did not forsake her fornications which she had committed in Egypt: for they also lay with her in her youth, and they bruised the breasts of her virginity, and poured out their fornication upon her.", "bbe": "And she has not given up her loose ways from the time when she was in Egypt; for when she was young they were her lovers, and by them her young breasts were crushed, and they let loose on her their unclean desire.", "geneva": "Neither left she her fornications, learned of the Egyptians: for in her youth they lay with her, and they bruised the breasts of her virginitie, and powred their whoredome vpon her.", "wycliffe": "Ferthermore and sche lefte not hir fornicaciouns, whiche sche hadde in Egipt; for whi and thei slepten with hir in the yongthe of hir, and thei braken the tetis of the tyme of mariage of hir, and thei scheden out her fornicacioun on hir.", "rotherham": "And, her unchaste doings from the time she was in Egypt, had she not forsaken, For with her, had they lain in her youth, Yea they had pressed her virgin bosoms,- and had poured out their unchastity upon her.", "darby": "Neither left she her whoredoms [brought] from Egypt; for in her youth they had lain with her, and had handled the breasts of her virginity, and poured their fornication upon her.", "twenty": "", "jps": "Neither hath she left her harlotries brought from Egypt; for in her youth they lay with her, and they bruised her virgin breasts; and they poured out their lust upon her.", "acv": "Neither has she left her whoredoms since Egypt. For in her youth they lie with her, and they handled the bosom of her virginity, and they poured out their whoredom upon her.", "anderson": "", "haweis": "", "noyes": "Neither forsook she her whoredoms brought from Egypt; for they lay with her in her youth, and handled the breasts of her virginity, and poured their fornication upon her.", "webster": "Neither left she her lewd deeds [brought] from Egypt: for in her youth they lay with her, and they first corrupted her, and poured their impurities upon her.", "vulgate": "insuper et fornicationes suas quas habuerat in Aegypto non reliquit nam et illi dormierant cum ea in adulescentia eius et illi confregerant ubera pubertatis eius et effuderant fornicationem suam super eam;", "brenton": "And she forsook not her fornication with the Egyptians: for in her youth they committed fornication with her, and they deflowered her, and poured out their fornication upon her."}}, {"v": 9, "ref": "23:9", "o": "לָ/כֵ֥ן נְתַתִּ֖י/הָ בְּ/יַד מְאַֽהֲבֶ֑י/הָ בְּ/יַד֙ בְּנֵ֣י אַשּׁ֔וּר אֲשֶׁ֥ר עָגְבָ֖ה עֲלֵי/הֶֽם", "en": {"kjv": "Wherefore I have delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "web": "Therefore I delivered her into the hand of her lovers, into the hand of the Assyrians, on whom she doted.", "bsb": "Therefore I delivered her into the hands of her lovers, the Assyrians for whom she lusted.", "asv": "Wherefore I delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "ylt": "Therefore I have given her into the hand of her lovers, Into the hand of sons of Asshur on whom she doted.", "dra": "Therefore have I delivered her into the hands of her lovers, into the hands of the sons of the Assyrians, upon whose lust she doted.", "bbe": "For this cause I gave her up into the hands of her lovers, into the hands of the Assyrians on whom her desire was fixed.", "geneva": "Wherefore I deliuered her into the hands of her louers, euen into the hands of the Assyrians, vpon whome she doted.", "wycliffe": "Therfor Y yaf hir in to the hondis of hir louyeris, in to the hondis of the sones of Assur, on whos letcherie sche was wood.", "rotherham": "therefore, did I deliver her into the hand of her lovers,- into the hand of the sons of Assyria, after whom she lusted:", "darby": "Therefore I gave her into the hand of her lovers, into the hand of the children of Asshur, after whom she lusted.", "twenty": "", "jps": "Wherefore I delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "acv": "Therefore I delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "anderson": "", "haweis": "", "noyes": "Wherefore I delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "webster": "Wherefore I have delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.", "vulgate": "propterea tradidi eam in manu amatorum suorum in manus filiorum Assur super quorum insanivit libidinem;", "brenton": "Therefore I delivered her into the hands of her lovers, into the hands of the children of the Assyrians, on whom she doted."}}, {"v": 10, "ref": "23:10", "o": "הֵמָּה֮ גִּלּ֣וּ עֶרְוָתָ/הּ֒ בָּנֶ֤י/הָ וּ/בְנוֹתֶ֨י/הָ֙ לָקָ֔חוּ וְ/אוֹתָ֖/הּ בַּ/חֶ֣רֶב הָרָ֑גוּ וַ/תְּהִי שֵׁם֙ לַ/נָּשִׁ֔ים וּ/שְׁפוּטִ֖ים עָ֥שׂוּ בָֽ/הּ", "en": {"kjv": "These discovered her nakedness: they took her sons and her daughters, and slew her with the sword: and she became famous among women; for they had executed judgment upon her.", "web": "These uncovered her nakedness; they took her sons and her daughters; and her they killed with the sword: and she became a byword among women; for they executed judgments on her.", "bsb": "They exposed her nakedness, seized her sons and daughters, and put her to the sword. Thus she became a byword among women, and they executed judgment against her.", "asv": "These uncovered her nakedness; they took her sons and her daughters; and her they slew with the sword: and she became a byword among women; for they executed judgments upon her.", "ylt": "They have uncovered her nakedness, Her sons and her daughters they have taken, And her by sword they have slain, And she is a name for women, And judgments they have done with her.", "dra": "They discovered her disgrace, took away her sons and daughters, and slew her with the sword: and they became infamous women, and they executed judgments in her.", "bbe": "By these her shame was uncovered: they took her sons and daughters and put her to death with the sword: and she became a cause of wonder to women; for they gave her the punishment which was right.", "geneva": "These discouered her shame: they tooke away her sonnes and her daughters, and slewe her with the sworde, and she had an euill name among women: for they had executed iudgement vpon her.", "wycliffe": "Thei diskyueriden the schenschipe of hir; thei token awei the sones and the douytris of hir, and killiden hir with swerd; and the wymmen weren maad famouse, that is, sclaundrid, and thei diden domes in hir.", "rotherham": "They disclosed her shame, Her sons and her daughters:, took they away, And herself—with the sword, they slew,— Thus became she a by-word among women, when judgments, they had executed upon her.", "darby": "These discovered her nakedness, they took her sons and her daughters, and slew her with the sword; and she became a name among women; and they executed judgment upon her.", "twenty": "", "jps": "These uncovered her nakedness; they took her sons and her daughters, and her they slew with the sword; and she became a byword among women, for judgments were executed upon her.", "acv": "These uncovered her nakedness. They took her sons and her daughters, and they killed her with the sword. And she became a byword among women, for they executed judgments upon her.", "anderson": "", "haweis": "", "noyes": "These uncovered her nakedness; they took her sons and her daughters, and slew her with the sword; and she became famous among women, when they had executed judgment upon her.", "webster": "These uncovered her nakedness: they took her sons and her daughters, and slew her with the sword: and she became famous among women; for they had executed judgment upon her.", "vulgate": "ipsi discoperuerunt ignominiam eius filios et filias illius tulerunt et ipsam occiderunt gladio et factae sunt famosae mulieres et iudicia perpetrarunt in ea;", "brenton": "They uncovered her shame: they took her sons and daughters, and slew her with the sword: and she became a byword among women: and they wrought vengeance in her for the sake of the daughters."}}, {"v": 11, "ref": "23:11", "o": "וַ/תֵּ֨רֶא֙ אֲחוֹתָ֣/הּ אָהֳלִיבָ֔ה וַ/תַּשְׁחֵ֥ת עַגְבָתָ֖/הּ מִמֶּ֑/נָּה וְ/אֶת תַּ֨זְנוּתֶ֔י/הָ מִ/זְּנוּנֵ֖י אֲחוֹתָֽ/הּ", "en": {"kjv": "And when her sister Aholibah saw this, she was more corrupt in her inordinate love than she, and in her whoredoms more than her sister in her whoredoms.", "web": "Her sister Oholibah saw this, yet was she more corrupt in her doting than she, and in her prostitution which were more than the prostitution of her sister.", "bsb": "Her sister Oholibah saw this, yet in her lust and prostitution she was more depraved than her sister.", "asv": "And her sister Oholibah saw this, yet was she more corrupt in her doting than she, and in her whoredoms which were more than the whoredoms of her sister.", "ylt": "And see doth her sister Aholibah, And she maketh her doting love more corrupt than she, And her whoredoms than the whoredoms of her sister.", "dra": "And when her sister Ooliba saw this, she was mad with lust more than she: and she carried her fornication beyond the fornication of her sister.", "bbe": "And her sister Oholibah saw this, but her desire was even more unmeasured, and her loose behaviour was worse than that of her sister.", "geneva": "And when her sister Aholibah sawe this, she marred her selfe with inordinate loue, more then she, and with her fornications more then her sister with her fornications.", "wycliffe": "And whanne hir sistir Ooliba hadde seyn this, sche was wood in letcherie more than that sistre, and yaf vnschamefastli hir fornicacioun on the fornicacioun of hir sistre,", "rotherham": "And though her sister Oholibah saw, Yet became she more corrupt in her lust than the other,- And her unchaste doings exceeded the unchaste doings of her sister.", "darby": "And her sister Oholibah saw [this], and was more corrupt in her passion than she, and in her fornications more than the whoredoms of her sister.", "twenty": "", "jps": "And her sister Oholibah saw this, yet was she more corrupt in her doting than she, and in her harlotries more than her sister in her harlotries.", "acv": "And her sister Oholibah saw this, yet she was more corrupt in her doting than she, and in her whoredoms which were more than the whoredoms of her sister.", "anderson": "", "haweis": "", "noyes": "And her sister, Aholibah, saw this, but she was more corrupt in her inordinate love than she, and in her whoredoms more than her sister in her whoredoms.", "webster": "And when her sister Aholibah saw [this], she was more corrupt in her inordinate love than she, and in her prostitutions more than her sister in [her] prostitutions.", "vulgate": "quod cum vidisset soror eius Ooliba plus quam illa insanivit libidine et fornicationem suam super fornicationem sororis suae;", "brenton": "And her sister Ooliba saw it, and she indulged in her fondness more corruptly than she, and in her fornication more than the fornication of her sister."}}, {"v": 12, "ref": "23:12", "o": "אֶל בְּנֵי֩ אַשּׁ֨וּר עָגָ֜בָה פַּח֨וֹת וּ/סְגָנִ֤ים קְרֹבִים֙ לְבֻשֵׁ֣י מִכְל֔וֹל פָּרָשִׁ֖ים רֹכְבֵ֣י סוּסִ֑ים בַּח֥וּרֵי חֶ֖מֶד כֻּלָּֽ/ם", "en": {"kjv": "She doted upon the Assyrians her neighbours, captains and rulers clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.", "web": "She doted on the Assyrians, governors and rulers, her neighbors, clothed most gorgeously, horsemen riding on horses, all of them desirable young men.", "bsb": "She too lusted after the Assyrians—governors and commanders, warriors dressed in splendor, horsemen riding on steeds, all desirable young men.", "asv": "She doted upon the Assyrians, governors and rulers, her neighbors, clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.", "ylt": "On sons of Asshur she hath doted, Governors and prefects, Neighbouring ones--clothed in perfection, Horsemen, riding on horses, Desirable young men all of them.", "dra": "Impudently prostituting herself to the children of the Assyrians, the princes, and rulers that came to her, clothed with divers colours, to the horsemen that rode upon horses, and to young men all of great beauty.", "bbe": "She was full of desire for the Assyrians, captains and rulers, her neighbours, clothed in blue, horsemen going on horses, all of them young men to be desired.", "geneva": "She doted vpon the Assyrians her neighbours, both captaines and princes clothed with diuers sutes, horsemen ryding vpon horses: they were all pleasant yong men.", "wycliffe": "to the sones of Assiriens, to duykis and magistratis comynge to hir, that weren clothid with dyuerse cloth, to knyytis that weren borun on horsis, and to yonge men with noble schap, to alle men.", "rotherham": "After the sons of Assyria:, she lusted Governors and deputies so warlike. Clothed in splendid array, Horsemen, riding on horses, Attractive young men, all of them.", "darby": "She lusted after the children of Asshur [her] neighbours, governors and rulers, clothed most gorgeously, horsemen riding upon horses, all of them attractive young men.", "twenty": "", "jps": "She doted upon the Assyrians, governors and rulers, warriors, clothed most gorgeously, horsemen riding upon horses, all of them handsome young men.", "acv": "She doted upon the Assyrians, governors and rulers, her neighbors, clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.", "anderson": "", "haweis": "", "noyes": "She doted upon the Assyrians, her neighbors, prefects and rulers clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.", "webster": "She doted upon the Assyrians [her] neighbors, captains and rulers clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.", "vulgate": "ad filios Assyriorum praebuit inpudenter ducibus et magistratibus ad se venientibus indutis veste varia equitibus qui vectabantur equis et adulescentibus forma cunctis egregia;", "brenton": "She doted upon the sons of the Assyrian, princes and captains, her neighbours, clothed with fine linen, horsemen riding on horses; they were all choice young men."}}, {"v": 13, "ref": "23:13", "o": "וָ/אֵ֖רֶא כִּ֣י נִטְמָ֑אָה דֶּ֥רֶךְ אֶחָ֖ד לִ/שְׁתֵּי/הֶֽן", "en": {"kjv": "Then I saw that she was defiled, that they took both one way,", "web": "I saw that she was defiled; they both took one way.", "bsb": "And I saw that she too had defiled herself; both of them had taken the same path.", "asv": "And I saw that she was defiled; they both took one way.", "ylt": "And I see that she hath been defiled, One way is to them both.", "dra": "And I saw that she was defiled, and that they both took one way.", "bbe": "And I saw that she had become unclean; the two of them went the same way.", "geneva": "Then I sawe that she was defiled, and that they were both after one sort,", "wycliffe": "And Y siy that o weie of both sistris was defoulid,", "rotherham": "So I saw that she defiled herself,— One way, had they both.", "darby": "And I saw that she was defiled: both took one way.", "twenty": "", "jps": "And I saw that she was defiled; they both took one way.", "acv": "And I saw that she was defiled. They both took one way.", "anderson": "", "haweis": "", "noyes": "Then I saw that she was defiled; that they both took one way.", "webster": "Then I saw that she was defiled, [that] they [took] both one way.", "vulgate": "et vidi quod polluta esset via una ambarum;", "brenton": "And I saw that they were defiled, that the two had one way."}}, {"v": 14, "ref": "23:14", "o": "וַ/תּ֖וֹסֶף אֶל תַּזְנוּתֶ֑י/הָ וַ/תֵּ֗רֶא אַנְשֵׁי֙ מְחֻקֶּ֣ה עַל הַ/קִּ֔יר צַלְמֵ֣י כשדיים כַשְׂדִּ֔ים חֲקֻקִ֖ים בַּ/שָּׁשַֽׁר", "en": {"kjv": "And that she increased her whoredoms: for when she saw men pourtrayed upon the wall, the images of the Chaldeans pourtrayed with vermilion,", "web": "She increased her prostitution; for she saw men portrayed on the wall, the images of the Chaldeans portrayed with vermilion,", "bsb": "But Oholibah carried her prostitution even further. She saw the men portrayed on the wall, images of the Chaldeans, engraved in vermilion,", "asv": "And she increased her whoredoms; for she saw men portrayed upon the wall, the images of the Chaldeans portrayed with vermilion,", "ylt": "And she doth add unto her whoredoms, And she seeth graved men on the wall, Pictures of Chaldeans, graved with red lead,", "dra": "And she increased her fornications: and when she had seen men painted on the wall, the images of the Chaldeans set forth in colours,", "bbe": "And her loose behaviour became worse; for she saw men pictured on a wall, pictures of the Chaldaeans painted in bright red,", "geneva": "And that she encreased her fornications: for when she sawe men painted vpon the wall, the images of the Caldeans painted with vermelon,", "wycliffe": "and sche encreesside hir fornycaciouns. And whanne sche hadde seyn men peyntid in the wal, the ymagis of Caldeis expressid with colouris,", "rotherham": "Yet did she add, unto her unchaste doings, when she saw men portrayed upon the wall, likenesses of Chaldeans, Portrayed with vermilion:", "darby": "And she increased her fornications; for she saw men portrayed upon the wall, the images of the Chaldeans portrayed with vermilion,", "twenty": "", "jps": "And she increased her harlotries; for she saw men portrayed upon the wall, the images of the Chaldeans portrayed with vermilion,", "acv": "And she increased her whoredoms, for she saw men portrayed upon the wall, the images of the Chaldeans portrayed with vermilion,", "anderson": "", "haweis": "", "noyes": "But she added to her whoredoms; for she saw men portrayed upon the wall, images of Chaldaeans portrayed with vermilion,", "webster": "And [that] she increased her prostitutions: for when she saw men pourtrayed upon the wall, the images of the Chaldeans pourtrayed with vermilion.", "vulgate": "et auxit fornicationes suas cumque vidisset viros depictos in pariete imagines Chaldeorum expressas coloribus;", "brenton": "And she increased her fornication, and she saw men painted on the wall, likenesses of the Chaldeans painted with a pencil,"}}, {"v": 15, "ref": "23:15", "o": "חֲגוֹרֵ֨י אֵז֜וֹר בְּ/מָתְנֵי/הֶ֗ם סְרוּחֵ֤י טְבוּלִים֙ בְּ/רָ֣אשֵׁי/הֶ֔ם מַרְאֵ֥ה שָׁלִשִׁ֖ים כֻּלָּ֑/ם דְּמ֤וּת בְּנֵֽי בָבֶל֙ כַּשְׂדִּ֔ים אֶ֖רֶץ מוֹלַדְתָּֽ/ם", "en": {"kjv": "Girded with girdles upon their loins, exceeding in dyed attire upon their heads, all of them princes to look to, after the manner of the Babylonians of Chaldea, the land of their nativity:", "web": "dressed with girdles on their waists, with flowing turbans on their heads, all of them princes to look on, after the likeness of the Babylonians in Chaldea, the land of their birth.", "bsb": "wearing belts on their waists and flowing turbans on their heads; all of them looked like officers of the Babylonians in Chaldea, the land of their birth.", "asv": "girded with girdles upon their loins, with flowing turbans upon their heads, all of them princes to look upon, after the likeness of the Babylonians in Chaldea, the land of their nativity.", "ylt": "Girded with a girdle on their loins, Dyed attire spread out on their heads, The appearance of rulers--all of them, The likeness of sons of Babylon, Chaldea is the land of their birth.", "dra": "And girded with girdles about their reins, and with dyed turbans on their heads, the resemblance of all the captains, the likeness of the sons of Babylon, and of the land of the Chaldeans wherein they were born,", "bbe": "With bands round their bodies and with head-dresses hanging round their heads, all of them looking like rulers, like the Babylonians, the land of whose birth is Chaldaea.", "geneva": "And girded with girdles vpon their loynes, and with dyed attyre vpon their heads (looking all like princes after the maner of the Babylonians in Caldea, the land of their natiuitie)", "wycliffe": "and gird on the reynes with kniytis girdlis, and cappis peyntid in the heedis of hem, the foormes of alle duykis, the licnesse of the sones of Babiloyne, and of the lond of Caldeis, in which thei weren borun;", "rotherham": "Girded with waistcloths upon their loins With overhanging high turbans upon their heads, In appearance, knights all of them,-The likeness of the sons of Babylon of Chaldea, the land of their birth.", "darby": "girded with girdles upon their loins, with flowing turbans on their heads, all of them captains in appearance, [after] the likeness of the children of Babylon, of Chaldea, the land of their nativity.", "twenty": "", "jps": "girded with girdles upon their loins, with pendant turbans upon their heads, all of them captains to look upon, the likeness of the sons of Babylon, even of Chaldea, the land of their nativity.", "acv": "girded with belts upon their loins, with flowing turbans upon their heads, all of them rulers to look upon, according to the likeness of the Babylonians in Chaldea, the land of their nativity.", "anderson": "", "haweis": "", "noyes": "girded with girdles upon their loins, and having long mitres hanging down from their heads, in their appearance all of them princes, after the manner of the sons of Babylon, of Chaldaea, the land of their nativity;", "webster": "Girded with girdles upon their loins, exceeding in dyed attire upon their heads, all of them princes to look to, after the manner of the Babylonians of Chaldea, the land of their nativity:", "vulgate": "et accinctos balteis renes et tiaras tinctas in capitibus eorum formam ducum omnium similitudinem filiorum Babylonis terraeque Chaldeorum in qua orti sunt;", "brenton": "having variegated girdles on their loins, having also richly dyed attire upon their heads; all had a princely appearance, the likeness of the children of the Chaldeans, of their native land."}}, {"v": 16, "ref": "23:16", "o": "ו/תעגב וַ/תַּעְגְּבָ֥/ה עֲלֵי/הֶ֖ם לְ/מַרְאֵ֣ה עֵינֶ֑י/הָ וַ/תִּשְׁלַ֧ח מַלְאָכִ֛ים אֲלֵי/הֶ֖ם כַּשְׂדִּֽימָ/ה", "en": {"kjv": "And as soon as she saw them with her eyes, she doted upon them, and sent messengers unto them into Chaldea.", "web": "As soon as she saw them she doted on them, and sent messengers to them into Chaldea.", "bsb": "At the sight of them, she lusted for them and sent messengers to them in Chaldea.", "asv": "And as soon as she saw them she doted upon them, and sent messengers unto them into Chaldea.", "ylt": "And she doteth on them at the sight of her eyes, And sendeth messengers to them, to Chaldea.", "dra": "She doted upon them with the lust of her eyes, and she sent messengers to them into Chaldea.", "bbe": "And when she saw them she was full of desire for them, and sent servants to them in Chaldaea.", "geneva": "Assoone, I say, as she sawe them, she doted vpon them, and sent messengers vnto them into Caldea.", "wycliffe": "sche was wood on hem bi coueitise of hir iyen, and sche sente messangeris to hem in to Caldee.", "rotherham": "Then lusted she after them, as soon as her eyes beheld them,— And she sent messengers unto them to Chaldea.", "darby": "And as soon as she saw them with her eyes, she lusted after them, and sent messengers unto them into Chaldea.", "twenty": "", "jps": "And as soon as she saw them she doted upon them, and sent messengers unto them into Chaldea.", "acv": "And as soon as she saw them she doted upon them, and sent messengers to them into Chaldea.", "anderson": "", "haweis": "", "noyes": "and as soon as she cast her eyes upon them, she doted on them, and sent messengers to them into Chaldaea.", "webster": "And as soon as she saw them with her eyes she doted upon them, and sent messengers to them into Chaldea.", "vulgate": "et insanivit super eos concupiscentia oculorum suorum et misit nuntios ad eos in Chaldeam;", "brenton": "And she doted upon them as soon as she saw them, and sent forth messengers to them into the land of the Chaldeans."}}, {"v": 17, "ref": "23:17", "o": "וַ/יָּבֹ֨אוּ אֵלֶ֤י/הָ בְנֵֽי בָבֶל֙ לְ/מִשְׁכַּ֣ב דֹּדִ֔ים וַ/יְטַמְּא֥וּ אוֹתָ֖/הּ בְּ/תַזְנוּתָ֑/ם וַ/תִּ֨טְמָא בָ֔/ם וַ/תֵּ֥קַע נַפְשָׁ֖/הּ מֵ/הֶֽם", "en": {"kjv": "And the Babylonians came to her into the bed of love, and they defiled her with their whoredom, and she was polluted with them, and her mind was alienated from them.", "web": "The Babylonians came to her into the bed of love, and they defiled her with their prostitution, and she was polluted with them, and her soul was alienated from them.", "bsb": "Then the Babylonians came to her, to the bed of love, and in their lust they defiled her. But after she had been defiled by them, she turned away in disgust.", "asv": "And the Babylonians came to her into the bed of love, and they defiled her with their whoredom, and she was polluted with them, and her soul was alienated from them.", "ylt": "And come in unto her do sons of Babylon, To the bed of loves, And they defile her with their whoredoms, And she is defiled with them, And her soul is alienated from them.", "dra": "And when the sons of Babylon were come to her to the bed of love, they defiled her with their fornications, and she was polluted by them, and her soul was glutted with them.", "bbe": "And the Babylonians came to her, into the bed of love, and made her unclean with their loose desire, and she became unclean with them, and her soul was turned from them.", "geneva": "Nowe when the Babylonians came to her into the bed of loue, they defiled her with their fornication, and she was polluted with them, and her lust departed from them.", "wycliffe": "And whanne the sones of Babiloyne weren comun to hir, to the bed of tetis, thei defouliden hir in her letcheries of virgyns; and sche was defoulid of hem, and the soule of hir was fillid of hem.", "rotherham": "Then came in unto her the sons of Babylon into the bed of endearments, and defiled her with their unchaste doings,- And she defiled herself with them, And then was her soul torn from them.", "darby": "And the children of Babylon came to her into the bed of love, and they defiled her with their fornication; she too defiled herself with them, and her soul was alienated from them.", "twenty": "", "jps": "And the Babylonians came to her into the bed of love, and they defiled her with their lust; and she was polluted with them, and her soul was alienated from them.", "acv": "And the Babylonians came to her into the bed of love. And they defiled her with their whoredom, and she was polluted with them, and her soul was alienated from them.", "anderson": "", "haweis": "", "noyes": "And the sons of Babylon came to her into the bed of love, and they defiled her with their whoredoms, and she was polluted with them. She then became alienated from them.", "webster": "And the Babylonians came to her into the bed of love, and they defiled her with their lewdness, and she was polluted with them, and her mind was alienated from them.", "vulgate": "cumque venissent ad eam filii Babylonis ad cubile mammarum polluerunt eam stupris suis et polluta est ab eis et saturata est anima eius ab illis;", "brenton": "And the sons of Babylon came to her, into the bed of rest, and they defiled her in her fornication, and she was defiled by them, and her soul was alienated from them."}}, {"v": 18, "ref": "23:18", "o": "וַ/תְּגַל֙ תַּזְנוּתֶ֔י/הָ וַ/תְּגַ֖ל אֶת עֶרְוָתָ֑/הּ וַ/תֵּ֤קַע נַפְשִׁ/י֙ מֵֽ/עָלֶ֔י/הָ כַּ/אֲשֶׁ֛ר נָקְעָ֥ה נַפְשִׁ֖/י מֵ/עַ֥ל אֲחוֹתָֽ/הּ", "en": {"kjv": "So she discovered her whoredoms, and discovered her nakedness: then my mind was alienated from her, like as my mind was alienated from her sister.", "web": "So she uncovered her prostitution, and uncovered her nakedness: then my soul was alienated from her, like as my soul was alienated from her sister.", "bsb": "When Oholibah openly prostituted herself and exposed her nakedness, I turned away from her in disgust, just as I had turned away from her sister.", "asv": "So she uncovered her whoredoms, and uncovered her nakedness: then my soul was alienated from her, like as my soul was alienated from her sister.", "ylt": "And she revealeth her whoredoms, And she revealeth her nakedness, And alienated is My soul from off her, As alienated was My soul from off her sister.", "dra": "And she discovered her fornications, and discovered her disgrace: and my soul was alienated from her, as my soul was alienated from her sister.", "bbe": "So her loose behaviour was clearly seen and her shame uncovered: then my soul was turned from her as it had been turned from her sister.", "geneva": "So she discouered her fornication, and disclosed her shame: then mine heart forsooke her, like as mine heart had forsaken her sister.", "wycliffe": "Also sche made nakid hir fornicaciouns, and diskyuered hir schenschipe; and my soule yede awei fro hir, as my soule hadde go awei fro hir sistir.", "rotherham": "Thus disclosed she her unchaste desires, And disclosed her shame,- So my soul was torn from her, Just as my soul had been torn from her sister.", "darby": "And she discovered her whoredoms, and discovered her nakedness; and my soul was alienated from her, like as my soul was alienated from her sister.", "twenty": "", "jps": "So she uncovered her harlotries, and uncovered her nakedness; then My soul was alienated from her, like as My soul was alienated from her sister.", "acv": "So she uncovered her whoredoms, and uncovered her nakedness. Then my soul was alienated from her, just as my soul was alienated from her sister.", "anderson": "", "haweis": "", "noyes": "So she discovered her fornications, and discovered her nakedness. Then my mind was alienated from her, as it had been alienated from her sister.", "webster": "So she disclosed her lewd deeds, and exposed her nakedness: then my mind was alienated from her, as my mind was alienated from her sister.", "vulgate": "denudavit quoque fornicationes suas et discoperuit ignominiam suam et recessit anima mea ab ea sicut recesserat anima mea a sorore eius;", "brenton": "And she exposed her fornication, and exposed her shame: and my soul was alienated from her, even as my soul was alienated from her sister."}}, {"v": 19, "ref": "23:19", "o": "וַ/תַּרְבֶּ֖ה אֶת תַּזְנוּתֶ֑י/הָ לִ/זְכֹּר֙ אֶת יְמֵ֣י נְעוּרֶ֔י/הָ אֲשֶׁ֥ר זָנְתָ֖ה בְּ/אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "Yet she multiplied her whoredoms, in calling to remembrance the days of her youth, wherein she had played the harlot in the land of Egypt.", "web": "Yet she multiplied her prostitution, remembering the days of her youth, in which she had played the prostitute in the land of Egypt.", "bsb": "Yet she multiplied her promiscuity, remembering the days of her youth, when she had prostituted herself in the land of Egypt", "asv": "Yet she multiplied her whoredoms, remembering the days of her youth, wherein she had played the harlot in the land of Egypt.", "ylt": "And she multiplieth her whoredoms, To remember the days of her youth, When she went a-whoring in the land of Egypt.", "dra": "For she multiplied her fornications, remembering the days of her youth, in which she played the harlot in the land of Egypt.", "bbe": "But still she went on the more with her loose behaviour, keeping in mind the early days when she had been a loose woman in the land of Egypt.", "geneva": "Yet she encreased her whoredome more, and called to remembrance ye dayes of her youth, wherein she had played the harlot in the land of Egypt.", "wycliffe": "For sche multiplied hir fornicaciouns, and hadde mynde on the daies of hir yongthe, in whiche sche dide fornicacioun in the lond of Egipt.", "rotherham": "Yea she multiplied her unchaste desires,-calling to mind the days of her youth, when she was unchaste in the land of Egypt; -", "darby": "Yet she multiplied her whoredoms, calling to remembrance the days of her youth, wherein she played the harlot in the land of Egypt;", "twenty": "", "jps": "Yet she multiplied her harlotries, remembering the days of her youth, wherein she had played the harlot in the land of Egypt.", "acv": "Yet she multiplied her whoredoms, remembering the days of her youth in which she had played the harlot in the land of Egypt.", "anderson": "", "haweis": "", "noyes": "For she multiplied her whoredoms in calling to remembrance the days of her youth, wherein she played the harlot in the land of Egypt;", "webster": "Yet she multiplied her prostitutions, in calling to remembrance the days of her youth, in which she had played the harlot in the land of Egypt.", "vulgate": "multiplicavit enim fornicationes suas recordans dies adulescentiae suae quibus fornicata est in terra Aegypti;", "brenton": "And thou didst multiply thy fornication, so as to call to remembrance the days of thy youth, wherein thou didst commit whoredom in Egypt,"}}, {"v": 20, "ref": "23:20", "o": "וַֽ/תַּעְגְּבָ֔/ה עַ֖ל פִּֽלַגְשֵׁי/הֶ֑ם אֲשֶׁ֤ר בְּשַׂר חֲמוֹרִים֙ בְּשָׂרָ֔/ם וְ/זִרְמַ֥ת סוּסִ֖ים זִרְמָתָֽ/ם", "en": {"kjv": "For she doted upon their paramours, whose flesh is as the flesh of asses, and whose issue is like the issue of horses.", "web": "She doted on their paramours, whose flesh is as the flesh of donkeys, and whose issue is like the issue of horses.", "bsb": "and lusted after their lovers, whose genitals were like those of donkeys and whose emission was like that of stallions.", "asv": "And she doted upon their paramours, whose flesh is as the flesh of asses, and whose issue is like the issue of horses.", "ylt": "And she doteth on their paramours, Whose flesh is the flesh of asses, And the issue of horses--their issue.", "dra": "And she was mad with lust after lying with them whose flesh is as the flesh of asses: and whose issue as the issue of horses.", "bbe": "And she was full of desire for her lovers, whose flesh is like the flesh of asses and whose seed is like the seed of horses.", "geneva": "For she doted vpon their seruants whose members are as the members of asses, and whose yssue is like the yssue of horses.", "wycliffe": "And sche was wood in letcherie on the liggyng bi of hem, whos fleischis ben as the fleischis of assis, and as the membris of horsis ben the membris of hem.", "rotherham": "So she lusted after their courtiers,- Whose flesh was the flesh of asses, and Whose issue was the issue of horses.", "darby": "and she lusted after their paramours, whose flesh is [as] the flesh of asses, and whose issue is [as] the issue of horses.", "twenty": "", "jps": "And she doted upon concubinage with them, whose flesh is as the flesh of asses, and whose issue is like the issue of horses.", "acv": "And she doted upon their paramours, whose flesh is as the flesh of donkeys, and whose issue is like the issue of horses.", "anderson": "", "haweis": "", "noyes": "for she doted on their paramours, whose members were as the members of asses, and whose issue was as the issue of horses.", "webster": "For she doted upon their paramours, whose flesh [is as] the flesh of asses, and whose issue [is like] the issue of horses.", "vulgate": "et insanivit libidine super concubitu eorum quorum carnes sunt ut carnes asinorum et sicut fluxus equorum fluxus eorum;", "brenton": "and thou didst dote upon the Chaldeans, whose flesh is as the flesh of the asses, and their members as the members of horses."}}, {"v": 21, "ref": "23:21", "o": "וַֽ/תִּפְקְדִ֔י אֵ֖ת זִמַּ֣ת נְעוּרָ֑יִ/ךְ בַּ/עְשׂ֤וֹת מִ/מִּצְרַ֨יִם֙ דַּדַּ֔יִ/ךְ לְמַ֖עַן שְׁדֵ֥י נְעוּרָֽיִ/ךְ", "en": {"kjv": "Thus thou calledst to remembrance the lewdness of thy youth, in bruising thy teats by the Egyptians for the paps of thy youth.", "web": "Thus you called to memory the lewdness of your youth, in the handling of your bosom by the Egyptians for the breasts of your youth.", "bsb": "So you revisited the indecency of your youth, when the Egyptians caressed your bosom and pressed your young breasts.", "asv": "Thus thou calledst to remembrance the lewdness of thy youth, in the handling of thy bosom by the Egyptians for the breasts of thy youth.", "ylt": "Thou lookest after the wickedness of thy youth, In dealing out of Egypt thy loves, For the sake of the breasts of thy youth.", "dra": "And thou hast renewed the wickedness of thy youth, when thy breasts were pressed in Egypt, and the paps of thy virginity broken.", "bbe": "And she made the memory of the loose ways of her early years come back to mind, when her young breasts were crushed by the Egyptians.", "geneva": "Thou calledst to remembrance the wickednes of thy youth, when thy teates were bruised by ye Egyptians: therefore ye paps of thy youth are thus.", "wycliffe": "And thou visitidist the grete trespas of thi yongthe, whanne thi brestis weren maad low in Egipt, and the tetis of the tyme of thi mariage weren brokun.", "rotherham": "Yea thou didst look about for the lewdness of thy youth,- When were pressed by the Egyptians. thy bosoms, When they handled thy youthful breasts.", "darby": "And thou didst look back to the lewdness of thy youth, in the handling of thy teats by the Egyptians, for the breasts of thy youth.", "twenty": "", "jps": "Thus thou didst call to remembrance the lewdness of thy youth, when they from Egypt bruised thy breasts for the bosom of thy youth.", "acv": "Thus thou called to remembrance the lewdness of thy youth, in the handling of thy bosom by the Egyptians for the breasts of thy youth.", "anderson": "", "haweis": "", "noyes": "Thus thou calledst to remembrance the lewdness of thy youth, when thy teats were handled by the Egyptians, on account of the paps of thy youth.", "webster": "Thus thou calledst to remembrance the lewdness of thy youth, by being corrupted by the Egyptians in thy youth.", "vulgate": "et visitasti scelus adulescentiae tuae quando subacta sunt in Aegypto ubera tua et confractae mammae pubertatis tuae;", "brenton": "And thou didst look upon the iniquity of thy youth, the things which thou wroughtest in Egypt in thy lodgings, where were the breasts of thy youth."}}, {"v": 22, "ref": "23:22", "o": "לָ/כֵ֣ן אָהֳלִיבָ֗ה כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִנְ/נִ֨י מֵעִ֤יר אֶת מְאַהֲבַ֨יִ/ךְ֙ עָלַ֔יִ/ךְ אֵ֛ת אֲשֶׁר נָקְעָ֥ה נַפְשֵׁ֖/ךְ מֵ/הֶ֑ם וַ/הֲבֵאתִ֥י/ם עָלַ֖יִ/ךְ מִ/סָּבִֽיב", "en": {"kjv": "Therefore, O Aholibah, thus saith the Lord God; Behold, I will raise up thy lovers against thee, from whom thy mind is alienated, and I will bring them against thee on every side;", "web": "Therefore, Oholibah, thus says the Lord Yahweh: Behold, I will raise up your lovers against you, from whom your soul is alienated, and I will bring them against you on every side:", "bsb": "Therefore, Oholibah, this is what the Lord GOD says: ‘I will incite your lovers against you, those from whom you turned away in disgust. And I will bring them against you from every side—", "asv": "Therefore, O Oholibah, thus saith the Lord Jehovah: Behold, I will raise up thy lovers against thee, from whom thy soul is alienated, and I will bring them against thee on every side:", "ylt": "Therefore, O Aholibah, thus said the Lord Jehovah: Lo, I am stirring up thy lovers against thee, From whom thy soul hath been alienated, And have brought them in against thee from round about.", "dra": "Therefore, Ooliba, thus saith the Lord God: Behold I will raise up against thee all thy lovers with whom thy soul hath been glutted: and I will gather them together against thee round about.", "bbe": "For this cause, O Oholibah, this is what the Lord has said: See, I will make your lovers come up against you, even those from whom your soul is turned away in disgust; and I will make them come up against you on every side;", "geneva": "Therefore, O Aholibah, thus sayeth the Lord God, Beholde, I will raise vp thy louers against thee, from whome thine heart is departed, and I will bring them against thee on euery side,", "wycliffe": "Therfor, thou Ooliba, the Lord God seith these thingis, Lo! Y schal reise alle thi louyeris ayens thee, of whiche thi soule was fillid, and Y schal gadere hem ayens thee in cumpas;", "rotherham": "Therefore, O Oholibah, Thus saith My Lord Yahweh, Behold me! rousing up thy lovers against thee, Even them from whom thy soul hath been torn,- And I will bring them against thee from every side:", "darby": "Therefore, Oholibah, thus saith the Lord Jehovah: Behold, I will raise up thy lovers against thee, from whom thy soul is alienated, and I will bring them against thee on every side.", "twenty": "", "jps": "Therefore, O Oholibah, thus saith the L-rd GOD: Behold, I will raise up thy lovers against thee, from whom thy soul is alienated, and I will bring them against thee on every side:", "acv": "Therefore, O Oholibah, thus says the lord Jehovah: Behold, I will raise up thy lovers against thee, from whom thy soul is alienated, and I will bring them against thee on every side:", "anderson": "", "haweis": "", "noyes": "Therefore, O Aholibah, thus saith the Lord Jehovah: Behold, I will raise up against thee thy lovers, from whom thou art alienated, and I will bring them against thee on every side,", "webster": "Therefore, O Aholibah, thus saith the Lord GOD; Behold, I will raise up thy lovers against thee, from whom thy mind is alienated, and I will bring them against thee on every side;", "vulgate": "propterea Ooliba haec dicit Dominus Deus ecce ego suscitabo omnes amatores tuos contra te de quibus satiata est anima tua et congregabo eos adversum te in circuitu;", "brenton": "Therefore, Ooliba, thus saith the Lord; Behold, I will stir up thy lovers against thee, from whom thy soul is alienated, and I will bring them upon thee round about,"}}, {"v": 23, "ref": "23:23", "o": "בְּנֵ֧י בָבֶ֣ל וְ/כָל כַּשְׂדִּ֗ים פְּק֤וֹד וְ/שׁ֨וֹעַ֙ וְ/ק֔וֹעַ כָּל בְּנֵ֥י אַשּׁ֖וּר אוֹתָ֑/ם בַּח֨וּרֵי חֶ֜מֶד פַּח֤וֹת וּ/סְגָנִים֙ כֻּלָּ֔/ם שָֽׁלִשִׁים֙ וּ/קְרוּאִ֔ים רֹכְבֵ֥י סוּסִ֖ים כֻּלָּֽ/ם", "en": {"kjv": "The Babylonians, and all the Chaldeans, Pekod, and Shoa, and Koa, and all the Assyrians with them: all of them desirable young men, captains and rulers, great lords and renowned, all of them riding upon horses.", "web": "the Babylonians and all the Chaldeans, Pekod, Shoa, Koa, and all the Assyrians with them; desirable young men, governors and rulers all of them, princes and men of renown, all of them riding on horses.", "bsb": "the Babylonians and all the Chaldeans, the men of Pekod, Shoa, and Koa, and all the Assyrians with them—all desirable young men, governors and commanders, officers and men of renown, mounted on horses.", "asv": "the Babylonians and all the Chaldeans, Pekod and Shoa and Koa, and all the Assyrians with them; desirable young men, governors and rulers all of them, princes and men of renown, all of them riding upon horses.", "ylt": "Sons of Babylon, and of all Chaldea, Pekod, and Shoa, and Koa, All the sons of Asshur with them, Desirable young men, governors and prefects, All of them--rulers and proclaimed ones, Riding on horses, all of them.", "dra": "The children of Babylon, and all the Chaldeans, the nobles, and the kings, and princes, all the sons of the Assyrians, beautiful young men, all the captains, and rulers, the princes of princes, and the renowned horsemen.", "bbe": "The Babylonians and all the Chaldaeans, Pekod and Shoa and Koa, and all the Assyrians with them: young men to be desired, captains and rulers all of them, and chiefs, her neighbours, all of them on horseback.", "geneva": "To wit, the Babylonians, and all the Caldeans, Peked, and Shoah, and Koa, and all the Assyrians with them: they were all pleasant yong men, captaines and princes: all they were valiant and renoumed, riding vpon horses.", "wycliffe": "the sones of Babiloyne, and alle Caldeis, noble and miyti men, and princes, alle the sones of Assiriens, and yonge men of noble foorme, duykis, and magistratis, alle princes of princes, and named stieris of horsis.", "rotherham": "The sons of Babylon and all Chaldeans Pekod and Shoa and Koa, All the sons of Assyria with them,— Attractive young men Governors and deputies, all of them. Knights and men of renown, Riders on horses all of them;", "darby": "The children of Babylon, and all the Chaldeans, Pekod and Shoa and Koa, all the children of Asshur with them; all of them attractive young men, governors and rulers, great lords and renowned, all of them riding upon horses.", "twenty": "", "jps": "the Babylonians and all the Chaldeans, Pekod and Shoa and Koa, and all the Assyrians with them, handsome young men, governors and rulers all of them, captains and councillors, all of them riding upon horses.", "acv": "the Babylonians and all the Chaldeans, Pekod and Shoa and Koa, and all the Assyrians with them, desirable young men, governors and rulers all of them, rulers and men of renown, all of them riding upon horses.", "anderson": "", "haweis": "", "noyes": "the Babylonians and all the Chaldaeans, prefects, rich men, and nobles, and all the Assyrians with them, all of them desirable young men, prefects and rulers, captains and men of renown, all of them riding upon horses.", "webster": "The Babylonians, and all the Chaldeans, Pekod, and Shoa, and Koa, [and] all the Assyrians with them: all of them desirable young men, captains and rulers, great lords and renowned, all of them riding upon horses.", "vulgate": "filios Babylonis et universos Chaldeos nobiles tyrannosque et principes omnes filios Assyriorum iuvenes forma egregia duces et magistratus universos principes principum et nominatos ascensores equorum;", "brenton": "the children of Babylon, and all the Chaldeans, Phacuc, and Sue, and Hychue, and all the sons of the Assyrians with them; choice young men, governors and captains, all princes and renowned, riding on horses."}}, {"v": 24, "ref": "23:24", "o": "וּ/בָ֣אוּ עָלַ֡יִ/ךְ הֹ֠צֶן רֶ֤כֶב וְ/גַלְגַּל֙ וּ/בִ/קְהַ֣ל עַמִּ֔ים צִנָּ֤ה וּ/מָגֵן֙ וְ/קוֹבַ֔ע יָשִׂ֥ימוּ עָלַ֖יִ/ךְ סָבִ֑יב וְ/נָתַתִּ֤י לִ/פְנֵי/הֶם֙ מִשְׁפָּ֔ט וּ/שְׁפָט֖וּ/ךְ בְּ/מִשְׁפְּטֵי/הֶֽם", "en": {"kjv": "And they shall come against thee with chariots, wagons, and wheels, and with an assembly of people, which shall set against thee buckler and shield and helmet round about: and I will set judgment before them, and they shall judge thee according to their judgments.", "web": "They shall come against you with weapons, chariots, and wagons, and with a company of peoples; they shall set themselves against you with buckler and shield and helmet all around; and I will commit the judgment to them, and they shall judge you according to their judgments.", "bsb": "They will come against you with a host of peoples, with weapons, chariots, and wagons. They will array themselves against you on every side with buckler and shield and helmet. I will delegate judgment to them, and they will punish you according to their own standards.", "asv": "And they shall come against thee with weapons, chariots, and wagons, and with a company of peoples; they shall set themselves against thee with buckler and shield and helmet round about: and I will commit the judgment unto them, and they shall judge thee according to their judgments.", "ylt": "And they have come in against thee, With arms, rider, and wheel, And with an assembly of peoples; Target, and shield, and helmet, They do set against thee round about, And I have set before them judgment, They have judged thee in their Judgments.", "dra": "And they shall come upon thee well appointed with chariot and wheel, a multitude of people: they shall be armed against thee on every side with breastplate, and buckler, and helmet: and I will set judgment before them, and they shall judge thee by their judgments.", "bbe": "And they will come against you from the north on horseback, with war-carriages and a great band of peoples; they will put themselves in order against you with breastplate and body-cover and metal head-dress round about you: and I will make them your judges, and they will give their decision against you as seems right to them.", "geneva": "Euen these shall come against thee with charets, waggons, and wheeles, and with a multitude of people, which shall set against thee, buckler and shield, and helmet round about: and I will leaue the punishment vnto them, and they shall iudge thee according to their iudgements.", "wycliffe": "And thei araied with chare and wheel schulen come on thee, the multitude of puplis schulen be armed with haburioun, and scheeld, and basynet, ayens thee on ech side; and Y schal yyue doom bifor hem, and thei schulen deme thee bi her domes.", "rotherham": "And they shall come upon thee— With battle-axe, chariot and wheel And with a gathered host of peoples, :Shield and buckler and helmet, will they array against thee on every side,- And I will put before them judgment, And they shall judge thee with their judgments;", "darby": "And they shall come against thee [with] armour, chariots and wheels, and with an assemblage of peoples; they shall set themselves against thee [with] target, and shield, and helmet round about; and I will put judgment before them, and they shall judge thee according to their judgments.", "twenty": "", "jps": "And they shall come against thee with hosts, chariots, and wheels, and with an assembly of peoples; they shall set themselves in array against thee with buckler and shield and helmet round about; and I will commit the judgment unto them, and they shall judge thee according to their judgments.", "acv": "And they shall come against thee with weapons, chariots, and wagons, and with a company of peoples. They shall set themselves against thee with buckler and shield and helmet round about. And I will commit the judgment to them, and they shall judge thee according to their judgments.", "anderson": "", "haweis": "", "noyes": "And they shall come against thee with arms, chariots and wheels, and with hosts of people; with buckler and shield and helmet shall they set themselves against thee on every side. And I will commit to them judgment, and they shall punish thee according to their punishments.", "webster": "And they shall come against thee with chariots, wagons, and wheels, and with an assembly of people, [which] shall set against thee buckler and shield and helmet on every side: and I will set judgment before them, and they shall judge thee according to their judgments.", "vulgate": "et venient super te instructi curru et rota multitudo populorum lorica et clypeo et galea armabuntur contra te undique et dabo coram eis iudicium et iudicabunt te iudiciis suis;", "brenton": "And they all shall come upon thee from the north, chariots and wheels, with a multitude of nations, shields and targets; and the enemy shall set a watch against thee round about: and I will set judgment before them, and they shall take vengeance on thee with their judgments."}}, {"v": 25, "ref": "23:25", "o": "וְ/נָתַתִּ֨י קִנְאָתִ֜/י בָּ֗/ךְ וְ/עָשׂ֤וּ אוֹתָ/ךְ֙ בְּ/חֵמָ֔ה אַפֵּ֤/ךְ וְ/אָזְנַ֨יִ/ךְ֙ יָסִ֔ירוּ וְ/אַחֲרִיתֵ֖/ךְ בַּ/חֶ֣רֶב תִּפּ֑וֹל הֵ֗מָּה בָּנַ֤יִ/ךְ וּ/בְנוֹתַ֨יִ/ךְ֙ יִקָּ֔חוּ וְ/אַחֲרִיתֵ֖/ךְ תֵּאָכֵ֥ל בָּ/אֵֽשׁ", "en": {"kjv": "And I will set my jealousy against thee, and they shall deal furiously with thee: they shall take away thy nose and thine ears; and thy remnant shall fall by the sword: they shall take thy sons and thy daughters; and thy residue shall be devoured by the fire.", "web": "I will set my jealousy against you, and they shall deal with you in fury; they shall take away your nose and your ears; and your residue shall fall by the sword: they shall take your sons and your daughters; and your residue shall be devoured by the fire.", "bsb": "And I will set My jealous rage against you, and they will deal with you in fury. They will cut off your noses and ears, and your survivors will fall by the sword. They will seize your sons and daughters, and your remnant will be consumed by fire.", "asv": "And I will set my jealousy against thee, and they shall deal with thee in fury; they shall take away thy nose and thine ears; and thy residue shall fall by the sword: they shall take thy sons and thy daughters; and thy residue shall be devoured by the fire.", "ylt": "And I have set My jealousy against thee, And they have dealt with thee in fury, Thy nose and thine ears they turn aside, And thy posterity by sword falleth, They, thy sons and thy daughters do take away, And thy posterity is devoured by fire.", "dra": "And I will set my jealousy against thee, which they shall execute upon thee with fury: they shall cut off thy nose and thy ears: and what remains shall fall by the sword: they shall take thy sons, and thy daughters, and thy residue shall be devoured by fire.", "bbe": "And my bitter feeling will be working against you, and they will take you in hand with passion; they will take away your nose and your ears, and the rest of you will be put to the sword: they will take your sons and daughters, and the rest of you will be burned up in the fire.", "geneva": "And I wil lay mine indignation vpon thee, and they shall deale cruelly with thee: they shall cut off thy nose and thine eares, and thy remnant shall fall by the sword: they shall cary away thy sonnes and thy daughters, and thy residue shall be deuoured by the fire.", "wycliffe": "And Y schal sette my feruour in thee, which thei schulen vse with thee in woodnesse; thei schulen kitte awei thi nose and thin eeris, and thei schulen sle with swerd tho thingis that weren left; thei schulen take thi sones and thi douytris, and thi laste thing schal be deuourid bi fier.", "rotherham": "When I set forth my jealousy against thee, Then will they deal with thee in indignation, :Thy nose and thine ears, will they remove, And that which is left of thee, by the sword, shall fall,— They, will take away thy sons and thy daughters, And that which is left of thee, shall be devoured by the fire;", "darby": "And I will set my jealousy against thee, and they shall deal furiously with thee: they shall cut off thy nose and thine ears, and thy remnant shall fall by the sword; they shall take thy sons and thy daughters; and thy residue shall be devoured by the fire.", "twenty": "", "jps": "And I will set My jealousy against thee, and they shall deal with thee in fury; they shall take away thy nose and thine ears, and thy residue shall fall by the sword; they shall take thy sons and thy daughters, and thy residue shall be devoured by the fire.", "acv": "And I will set my jealousy against thee, and they shall deal with thee in fury. They shall take away thy nose and thine ears, and thy residue shall fall by the sword. They shall take thy sons and thy daughters, and thy residue shall be devoured by the fire.", "anderson": "", "haweis": "", "noyes": "And I will set my jealousy against thee, and they shall deal with thee in fury; they shall take away thy nose and thine ears, and thy posterity shall fall by the sword. They shall take away thy sons and thy daughters, and thy posterity shall be consumed with fire.", "webster": "And I will set my jealousy against thee, and they shall deal furiously with thee: they shall take away thy nose and thy ears; and thy remnant shall fall by the sword: they shall take thy sons and thy daughters; and thy residue shall be devoured by the fire.", "vulgate": "et ponam zelum meum in te quem exercent tecum in furore nasum tuum et aures tuas praecident et quae remanserint gladio concident ipsi filios tuos et filias tuas capient et novissimum tuum devorabitur igni;", "brenton": "And I will bring upon thee my jealousy, and they shall deal with thee in great wrath: they shall take away thy nose and thine ears; and shall cast down thy remnant with the sword: they shall take thy sons and thy daughters; and thy remnant fire shall devour."}}, {"v": 26, "ref": "23:26", "o": "וְ/הִפְשִׁיט֖וּ/ךְ אֶת בְּגָדָ֑יִ/ךְ וְ/לָקְח֖וּ כְּלֵ֥י תִפְאַרְתֵּֽ/ךְ", "en": {"kjv": "They shall also strip thee out of thy clothes, and take away thy fair jewels.", "web": "They shall also strip you of your clothes, and take away your beautiful jewels.", "bsb": "They will strip off your clothes and take your fine jewelry.", "asv": "They shall also strip thee of thy clothes, and take away thy fair jewels.", "ylt": "And they have stripped thee of thy garments, And have taken thy beauteous jewels.", "dra": "And they shall strip thee of thy garments, and take away the instruments of thy glory.", "bbe": "And they will take all your clothing off you and take away your ornaments.", "geneva": "They shall also strip thee out of thy clothes, and take away thy fayre iewels.", "wycliffe": "And thei schulen make thee nakid of thi clothis, and thei schulen take awei the vessels of thi glorie.", "rotherham": "And they shall strip off thy raiment,- And take away thine adorning jewels!", "darby": "They shall also strip the of thy garments, and take away thy fair jewels.", "twenty": "", "jps": "They shall also strip thee of thy clothes, and take away thy fair jewels.", "acv": "They shall also strip thee of thy clothes, and take away thy fair jewels.", "anderson": "", "haweis": "", "noyes": "They shall also strip thee of thy garments, and take away thy fair jewels.", "webster": "They shall also strip thee of thy clothes, and take away thy fair jewels.", "vulgate": "et denudabunt te vestimentis tuis et tollent vasa gloriae tuae;", "brenton": "And they shall strip thee of thy raiment, and take away thine ornaments."}}, {"v": 27, "ref": "23:27", "o": "וְ/הִשְׁבַּתִּ֤י זִמָּתֵ/ךְ֙ מִמֵּ֔/ךְ וְ/אֶת זְנוּתֵ֖/ךְ מֵ/אֶ֣רֶץ מִצְרָ֑יִם וְ/לֹֽא תִשְׂאִ֤י עֵינַ֨יִ/ךְ֙ אֲלֵי/הֶ֔ם וּ/מִצְרַ֖יִם לֹ֥א תִזְכְּרִי עֽוֹד", "en": {"kjv": "Thus will I make thy lewdness to cease from thee, and thy whoredom brought from the land of Egypt: so that thou shalt not lift up thine eyes unto them, nor remember Egypt any more.", "web": "Thus will I make your lewdness to cease from you, and your prostitution from the land of Egypt; so that you shall not lift up your eyes to them, nor remember Egypt any more.", "bsb": "So I will put an end to your indecency and prostitution, which began in the land of Egypt, and you will not lift your eyes to them or remember Egypt anymore.’", "asv": "Thus will I make thy lewdness to cease from thee, and thy whoredom brought from the land of Egypt; so that thou shalt not lift up thine eyes unto them, nor remember Egypt any more.", "ylt": "And I have caused thy wickedness to cease from thee, And thy whoredoms out of the land of Egypt, And thou liftest not up thine eyes unto them, And Egypt thou dost not remember again.", "dra": "And I will put an end to thy wickedness in thee, and thy fornication brought out of the land of Egypt: neither shalt thou lift up thy eyes to them, nor remember Egypt any more.", "bbe": "So I will put an end to your evil ways and your loose behaviour which came from the land of Egypt: and your eyes will never be lifted up to them again, and you will have no more memory of Egypt.", "geneva": "Thus wil I make thy wickednes to cease from thee and thy fornication out of the land of Egypt: so that thou shalt not lift vp thine eyes vnto them, nor remember Egypt any more.", "wycliffe": "And Y schal make thi greet trespasse to reste fro thee, and thi fornicacioun fro the lond of Egipt; and thou schalt not reise thin iyen to hem, and thou schalt no more haue mynde on Egipt.", "rotherham": "Thus will I cause thy lewdness to cease, from thee Even thine unchastity brought from the land of Egypt,- So that thou shalt not lift up thine eyes unto them, And Egypt, shalt thou not call to mind any more.", "darby": "And I will make thy lewdness to cease from thee, and thy whoredom [brought] from the land of Egypt; and thou shalt not lift up thine eyes unto them, nor remember Egypt any more.", "twenty": "", "jps": "Thus will I make thy lewdness to cease from thee, and thy harlotry brought from the land of Egypt, so that thou shalt not lift up thine eyes unto them, nor remember Egypt any more.", "acv": "Thus I will make thy lewdness to cease from thee, and thy whoredom from the land of Egypt, so that thou shall not lift up thine eyes to them, nor remember Egypt any more.", "anderson": "", "haweis": "", "noyes": "Thus will I make thy lewdness to cease from thee, and thy whoredom brought from the land of Egypt, so that thou shalt not lift thine eyes to them, nor remember Egypt any more.", "webster": "Thus will I make thy lewdness to cease from thee, and thy adultery [brought] from the land of Egypt: so that thou shalt not lift up thy eyes to them, nor remember Egypt any more.", "vulgate": "et requiescere faciam scelus tuum de te et fornicationem tuam de terra Aegypti nec levabis oculos tuos ad eos et Aegypti non recordaberis amplius;", "brenton": "So I will turn back thine ungodliness from thee, and thy fornication from the land of Egypt: and thou shalt not lift up thine eyes upon them, and shalt no more remember Egypt."}}, {"v": 28, "ref": "23:28", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִי֙ נֹֽתְנָ֔/ךְ בְּ/יַ֖ד אֲשֶׁ֣ר שָׂנֵ֑את בְּ/יַ֛ד אֲשֶׁר נָקְעָ֥ה נַפְשֵׁ֖/ךְ מֵ/הֶֽם", "en": {"kjv": "For thus saith the Lord God; Behold, I will deliver thee into the hand of them whom thou hatest, into the hand of them from whom thy mind is alienated:", "web": "For thus says the Lord Yahweh: Behold, I will deliver you into the hand of them whom you hate, into the hand of them from whom your soul is alienated;", "bsb": "For this is what the Lord GOD says: ‘Surely I will deliver you into the hands of those you hate, from whom you turned away in disgust.", "asv": "For thus saith the Lord Jehovah: Behold, I will deliver thee into the hand of them whom thou hatest, into the hand of them from whom thy soul is alienated;", "ylt": "For thus said the Lord Jehovah: Lo, I am giving thee into a hand that thou hast hated, Into a hand from which thou wast alienated.", "dra": "For thus saith the Lord God: Behold, I will deliver thee into the hands of them whom thou hatest, into their hands with whom thy soul hath been glutted.", "bbe": "For this is what the Lord has said: See, I will give you up into the hands of those who are hated by you, into the hands of those from whom your soul is turned away in disgust:", "geneva": "For thus saith the Lord God, Behold, I wil deliuer thee into the hand of them, whome thou hatest: euen into the hands of them from whome thine heart is departed.", "wycliffe": "For the Lord God seith these thingis, Lo! Y schal yyue thee in to the hondis of hem whiche thou hatist, `in to the hondis of hem of whiche thi soule was fillid,", "rotherham": "For thus saith My Lord, Yahweh, Behold me! delivering thee up, into the hand of them whom thou hatest, Into the hand of them from whom thy soul hath been torn;", "darby": "For thus saith the Lord Jehovah: Behold, I will give thee over into the hand of them whom thou hatest, into the hand of them from whom thy soul is alienated.", "twenty": "", "jps": "For thus saith the L-rd GOD: Behold, I will deliver thee into the hand of them whom thou hatest, into the hand of them from whom thy soul is alienated;", "acv": "For thus says the lord Jehovah: Behold, I will deliver thee into the hand of those whom thou hate, into the hand of those from whom thy soul is alienated.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: Behold, I will deliver thee into the hand of them whom thou hatest, into the hand of them from whom thou art alienated.", "webster": "For thus saith the Lord GOD; Behold, I will deliver thee into the hand [of them] whom thou hatest, into the hand [of them] from whom thy mind is alienated:", "vulgate": "quia haec dicit Dominus Deus ecce ego tradam te in manu eorum quos odisti in manu de quibus satiata est anima tua;", "brenton": "Wherefore thus saith the Lord God; Behold, I will deliver thee into the hands of those whom thou hatest, from whom thy soul is alienated."}}, {"v": 29, "ref": "23:29", "o": "וְ/עָשׂ֨וּ אוֹתָ֜/ךְ בְּ/שִׂנְאָ֗ה וְ/לָקְחוּ֙ כָּל יְגִיעֵ֔/ךְ וַ/עֲזָב֖וּ/ךְ עֵירֹ֣ם וְ/עֶרְיָ֑ה וְ/נִגְלָה֙ עֶרְוַ֣ת זְנוּנַ֔יִ/ךְ וְ/זִמָּתֵ֖/ךְ וְ/תַזְנוּתָֽיִ/ךְ", "en": {"kjv": "And they shall deal with thee hatefully, and shall take away all thy labour, and shall leave thee naked and bare: and the nakedness of thy whoredoms shall be discovered, both thy lewdness and thy whoredoms.", "web": "and they shall deal with you in hatred, and shall take away all your labor, and shall leave you naked and bare; and the nakedness of your prostitution shall be uncovered, both your lewdness and your prostitution.", "bsb": "They will treat you with hatred, take all for which you have worked, and leave you naked and bare, so that the shame of your prostitution will be exposed. Your indecency and promiscuity", "asv": "and they shall deal with thee in hatred, and shall take away all thy labor, and shall leave thee naked and bare; and the nakedness of thy whoredoms shall be uncovered, both thy lewdness and thy whoredoms.", "ylt": "And they have dealt with thee in hatred, And they have taken all thy labour, And they have left thee naked and bare, And revealed hath been the nakedness of thy whoredoms, And the wickedness of thy whoredoms.", "dra": "And they shall deal with thee in hatred, and they shall take away all thy labours, and shall let thee go naked, and full of disgrace, and the disgrace of thy fornication shall be discovered, thy wickedness, and thy fornications.", "bbe": "And they will take you in hand with hate, and take away all the fruit of your work, and let you be unveiled and without clothing: and the shame of your loose behaviour will be uncovered, your evil designs and your loose ways.", "geneva": "And they shall handle thee despitefully, and shall take away all thy labour, and shall leaue thee naked and bare, and the shame of thy fornications shalbe discouered, both thy wickednes, and thy whoredome.", "wycliffe": "and thei schulen do with thee in hatrede. And thei schulen take awei alle thi trauels, and thei schulen leeue thee nakid, and ful of schenschipe; and the schenschipe of thi fornicaciouns schal be schewid. Thi greet", "rotherham": "And they shall deal with thee in hatred And take away all thy labour, And leave thee utterly naked,- And thine unchaste shame, shall be disclosed, with thy lewdness and unchastities,", "darby": "And they shall deal with thee in hatred, and shall take away all thy labour, and shall leave thee naked and bare; so that the nakedness of thy whoredoms shall be discovered, both thy lewdness and thy fornications.", "twenty": "", "jps": "and they shall deal with thee in hatred, and shall take away all thy labour, and shall leave thee naked and bare; and the nakedness of thy harlotries shall be uncovered, both thy lewdness and thy harlotries.", "acv": "And they shall deal with thee in hatred, and shall take away all thy labor, and shall leave thee naked and bare. And the nakedness of thy whoredoms shall be uncovered, both thy lewdness and thy whoredoms.", "anderson": "", "haweis": "", "noyes": "And they shall deal with thee in hatred, and take away all the fruits of thy labor from thee, and shall leave thee naked and bare; and thy nakedness shall be uncovered, with which thou hast committed lewdness and fornication and foul whoredom.", "webster": "And they shall treat thee with hatred, and shall take away all thy labor, and shall leave thee naked and bare: and the nakedness of thy prostitutions shall be disclosed, both thy lewdness and thy prostitutions.", "vulgate": "et agent tecum in odio et tollent omnes labores tuos et dimittent te nudam et ignominia plenam revelabitur ignominia fornicationum tuarum scelus tuum et fornicationes tuae;", "brenton": "And they shall deal with thee in hatred, and shall take all the fruits of thy labours and thy toils, and thou shalt be naked and bare: and the shame of thy fornication shall be exposed: and thy ungodliness and thy fornication"}}, {"v": 30, "ref": "23:30", "o": "עָשֹׂ֥ה אֵ֖לֶּה לָ֑/ךְ בִּ/זְנוֹתֵ/ךְ֙ אַחֲרֵ֣י גוֹיִ֔ם עַ֥ל אֲשֶׁר נִטְמֵ֖את בְּ/גִלּוּלֵי/הֶֽם", "en": {"kjv": "I will do these things unto thee, because thou hast gone a whoring after the heathen, and because thou art polluted with their idols.", "web": "These things shall be done to you, because you have played the prostitute after the nations, and because you are polluted with their idols.", "bsb": "have brought these things upon you, because you have prostituted yourself with the nations and defiled yourself with their idols.", "asv": "These things shall be done unto thee, for that thou hast played the harlot after the nations, and because thou art polluted with their idols.", "ylt": "To do these things to thee, In thy going a-whoring after nations, Because thou hast been defiled with their idols,", "dra": "They have done these things to thee, because thou hast played the harlot with the nations among which thou wast defiled with their idols.", "bbe": "They will do these things to you because you have been untrue to me, and have gone after the nations, and have become unclean with their images.", "geneva": "I wil doe these things vnto thee, because thou hast gone a whoring after the heathen, and because thou art polluted with their idoles.", "wycliffe": "trespas and thi fornycaciouns han do these thingis to thee; for thou didist fornicacioun aftir hethene men, among whiche thou were defoulid in the idols of hem.", "rotherham": "These things shall be done to thee, In that thou hast gone unchastely after the nations, Because thou hast defiled thyself with their manufactured gods.", "darby": "These things shall be done unto thee, because thou hast gone a whoring after the nations, because thou hast defiled thyself with their idols.", "twenty": "", "jps": "These things shall be done unto thee, for that thou hast gone astray after the nations, and because thou art polluted with their idols.", "acv": "These things shall be done to thee, because thou have played the harlot after the nations, and because thou are polluted with their idols.", "anderson": "", "haweis": "", "noyes": "These things will I do to thee, because thou hast committed whoredom with the nations, and hast been polluted with their idols.", "webster": "I will do these [things] to thee, because thou hast gone astray after the heathen, [and] because thou art polluted with their idols.", "vulgate": "fecerunt haec tibi quia fornicata es post gentes inter quas polluta es in idolis eorum;", "brenton": "brought this upon thee, in that thou wentest a-whoring after the nations, and didst defile thyself with their devices."}}, {"v": 31, "ref": "23:31", "o": "בְּ/דֶ֥רֶךְ אֲחוֹתֵ֖/ךְ הָלָ֑כְתְּ וְ/נָתַתִּ֥י כוֹסָ֖/הּ בְּ/יָדֵֽ/ךְ", "en": {"kjv": "Thou hast walked in the way of thy sister; therefore will I give her cup into thine hand.", "web": "You have walked in the way of your sister; therefore will I give her cup into your hand.", "bsb": "Because you have followed the path of your sister, I will put her cup into your hand.’", "asv": "Thou hast walked in the way of thy sister; therefore will I give her cup into thy hand.", "ylt": "In the way of thy sister thou hast walked, And I have given her cup into thy hand.", "dra": "Thou hast walked in the way of thy sister and I will give her cup into thy hand.", "bbe": "You have gone in the way of your sister; and I will give her cup into your hand.", "geneva": "Thou hast walked in the way of thy sister: therefore wil I giue her cup into thine hand.", "wycliffe": "Thou yedist in the weie of thi sister, and Y schal yyue the cuppe of hir in thin hond.", "rotherham": "In the way of thy sister, hast thou walked, Therefore will I put her cup into thy hand.", "darby": "Thou hast walked in the way of thy sister; and I have given her cup into thy hand.", "twenty": "", "jps": "In the way of thy sister hast thou walked; therefore will I give her cup into thy hand.", "acv": "Thou have walked in the way of thy sister, therefore I will give her cup into thy hand.", "anderson": "", "haweis": "", "noyes": "Thou hast walked in the way of thy sister, therefore will I give her cup into thy hand.", "webster": "Thou hast walked in the way of thy sister; therefore will I give her cup into thy hand.", "vulgate": "in via sororis tuae ambulasti et dabo calicem eius in manu tua;", "brenton": "Thou didst walk in the way of thy sister; and I will put her cup into thine hands."}}, {"v": 32, "ref": "23:32", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהֹוִ֔ה כּ֤וֹס אֲחוֹתֵ/ךְ֙ תִּשְׁתִּ֔י הָ/עֲמֻקָּ֖ה וְ/הָ/רְחָבָ֑ה תִּהְיֶ֥ה לִ/צְחֹ֛ק וּ/לְ/לַ֖עַג מִרְבָּ֥ה לְ/הָכִֽיל", "en": {"kjv": "Thus saith the Lord God; Thou shalt drink of thy sister’s cup deep and large: thou shalt be laughed to scorn and had in derision; it containeth much.", "web": "Thus says the Lord Yahweh: You will drink of your sister’s cup, which is deep and large; you will be ridiculed and held in derision; it contains much.", "bsb": "This is what the Lord GOD says: ‘You will drink your sister’s cup, a cup deep and wide. It will bring scorn and derision, for it holds so much.", "asv": "Thus saith the Lord Jehovah: Thou shalt drink of thy sister’s cup, which is deep and large; thou shalt be laughed to scorn and had in derision; it containeth much.", "ylt": "Thus said the Lord Jehovah: The cup of thy sister thou dost drink, The deep and the wide one, (Thou art for laughter and for scorn,) Abundant to contain.", "dra": "Thus saith the Lord God: Thou shalt drink thy sister's cup, deep and wide: thou shalt be had in derision and scorn, which containeth very much.", "bbe": "This is what the Lord has said: You will take a drink from your sister's cup, which is deep and wide: you will be laughed at and looked down on, more than you are able to undergo.", "geneva": "Thus saith ye Lord God, Thou shalt drinke of thy sisters cup, deepe and large: thou shalt be laughed to scorne and had in derision, because it containeth much.", "wycliffe": "The Lord God seith these thingis, Thou schalt drinke the cuppe of thi sistir, the depthe, and the broodnesse; thou that art most able to take, schalt be in to scornyng, and in to mouwyng.", "rotherham": "Thus, saith My Lord Yahweh, The cup of thy sister, shalt thou drink, The cup deep and large, Thou shalt become a laughingstock and a derision, much doth it contain!", "darby": "Thus saith the Lord Jehovah: Thou shalt drink of thy sister's cup deep and large; thou shalt be for a laughing-stock and a derision, [for] it containeth much.", "twenty": "", "jps": "Thus saith the L-rd GOD: Thou shalt drink of thy sister's cup, which is deep and large; thou shalt be for a scorn and a derision; it is full to the uttermost.", "acv": "Thus says the lord Jehovah: Thou shall drink of thy sister's cup, which is deep and large. Thou shall be laughed to scorn and had in derision. It contains much.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Thou shalt drink of thy sister’s cup, which is deep and large; it shall make thee a laughing-stock and a derision, for it containeth much.", "webster": "Thus saith the Lord GOD; Thou shalt drink of thy sister's cup deep and large: thou shalt be treated with scorn and had in derision; it containeth much.", "vulgate": "haec dicit Dominus Deus calicem sororis tuae bibes profundum et latum eris in derisum et in subsannationem quae es capacissima;", "brenton": "Thus saith the Lord; Drink thy sister's cup, deep and large, and full, to cause complete drunkenness."}}, {"v": 33, "ref": "23:33", "o": "שִׁכָּר֥וֹן וְ/יָג֖וֹן תִּמָּלֵ֑אִי כּ֚וֹס שַׁמָּ֣ה וּ/שְׁמָמָ֔ה כּ֖וֹס אֲחוֹתֵ֥/ךְ שֹׁמְרֽוֹן", "en": {"kjv": "Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of thy sister Samaria.", "web": "You shall be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of your sister Samaria.", "bsb": "You will be filled with drunkenness and grief, with a cup of devastation and desolation, the cup of your sister Samaria.", "asv": "Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of thy sister Samaria.", "ylt": "With drunkenness and sorrow thou art filled, A cup of astonishment and desolation, The cup of thy sister Samaria.", "dra": "Thou shalt be filled with drunkenness, and sorrow: with the cup of grief and sadness, with the cup of thy sister Samaria.", "bbe": "You will be broken and full of sorrow, with the cup of wonder and destruction, with the cup of your sister Samaria.", "geneva": "Thou shalt be filled with drunkennes and sorow, euen with the cup of destruction, and desolation, with the cup of thy sister Samaria.", "wycliffe": "Thou schalt be fillid with drunkenesse and sorewe, with the cuppe of mourenyng and of heuynesse, with the cuppe of thi sister Samarie.", "rotherham": "With drunkenness and grief, shalt thou be filled,- The cup of astonishment and desolation, The cup of thy sister Samaria;", "darby": "Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and desolation, the cup of thy sister Samaria;", "twenty": "", "jps": "Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and appalment, with the cup of thy sister Samaria.", "acv": "Thou shall be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of thy sister Samaria.", "anderson": "", "haweis": "", "noyes": "Thou shalt be filled with drunkenness and sorrow. A cup of astonishment and amazement is the cup of thy sister Samaria.", "webster": "Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of thy sister Samaria.", "vulgate": "ebrietate et dolore repleberis calice maeroris et tristitiae calice sororis tuae Samariae;", "brenton": "And thou shalt be thoroughly weakened; and the cup of destruction, the cup of thy sister Samaria,"}}, {"v": 34, "ref": "23:34", "o": "וְ/שָׁתִ֨ית אוֹתָ֜/הּ וּ/מָצִ֗ית וְ/אֶת חֲרָשֶׂ֛י/הָ תְּגָרֵ֖מִי וְ/שָׁדַ֣יִ/ךְ תְּנַתֵּ֑קִי כִּ֚י אֲנִ֣י דִבַּ֔רְתִּי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thou shalt even drink it and suck it out, and thou shalt break the sherds thereof, and pluck off thine own breasts: for I have spoken it, saith the Lord God.", "web": "You shall even drink it and drain it out, and you shall gnaw the broken pieces of it, and shall tear your breasts; for I have spoken it, says the Lord Yahweh.", "bsb": "You will drink it and drain it; you will dash it to pieces, and tear your breasts. For I have spoken,’ declares the Lord GOD.", "asv": "Thou shalt even drink it and drain it out, and thou shalt gnaw the sherds thereof, and shalt tear thy breasts; for I have spoken it, saith the Lord Jehovah.", "ylt": "And thou hast drunk it, and hast drained it , And its earthen ware thou dost gnaw, And thine own breasts thou pluckest off, For I have spoken, An affirmation of the Lord Jehovah,", "dra": "And thou shalt drink it, and shalt drink it up even to the dregs, and thou shalt devour the fragments thereof, thou shalt rend thy breasts: because I have spoken it, saith the Lord God.", "bbe": "And after drinking it and draining it out, you will take the last drops of it to the end, pulling off your breasts: for I have said it, says the Lord.", "geneva": "Thou shalt euen drinke it, and wring it out to the dregges, and thou shalt breake the sheards thereof, and teare thine owne breasts: for I haue spoken it, sayth the Lord God.", "wycliffe": "And thou schalt drynke it, and thou schalt drinke of til to the drastis, and thou schalt deuoure the relifs therof, and thou schalt to-reende thi brestis, for Y the Lord spak, seith the Lord God.", "rotherham": "Yea thou shalt drink it and drain it out And the sherds thereof, shalt thou gnaw And thy breasts, shalt thou tear out,- For, I, have spoken, Declareth My Lord. Yahweh.", "darby": "thou shalt even drink it and suck it out, and thou shalt gnaw the sherds thereof, and pluck off thine own breasts: for I have spoken [it], saith the Lord Jehovah.", "twenty": "", "jps": "Thou shalt even drink it and drain it, and thou shalt craunch the sherds thereof, and shalt tear thy breasts; for I have spoken it, saith the L-rd GOD.", "acv": "Thou shall even drink it and drain it out. And thou shall gnaw the shards of it, and shall tear thy breasts, for I have spoken it, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thou shalt even drink it and suck it out, and lick the sherds, and thou shalt tear thy breasts. For I have spoken it, saith the Lord Jehovah.", "webster": "Thou shalt even drink it, and empty it to the dregs, and thou shalt break its pieces, and pluck off thy own breasts: for I have spoken [it], saith the Lord GOD.", "vulgate": "et bibes illum et epotabis usque ad feces et fragmenta eius devorabis et ubera tua lacerabis quia ego locutus sum ait Dominus Deus;", "brenton": "drink thou it, and I will take away her feasts and her new moons: for I have spoken it, saith the Lord."}}, {"v": 35, "ref": "23:35", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֚עַן שָׁכַ֣חַתְּ אוֹתִ֔/י וַ/תַּשְׁלִ֥יכִי אוֹתִ֖/י אַחֲרֵ֣י גַוֵּ֑/ךְ וְ/גַם אַ֛תְּ שְׂאִ֥י זִמָּתֵ֖/ךְ וְ/אֶת תַּזְנוּתָֽיִ/ךְ", "en": {"kjv": "Therefore thus saith the Lord God; Because thou hast forgotten me, and cast me behind thy back, therefore bear thou also thy lewdness and thy whoredoms.", "web": "Therefore thus says the Lord Yahweh: Because you have forgotten me, and cast me behind your back, therefore you also bear your lewdness and your prostitution.", "bsb": "Therefore this is what the Lord GOD says: ‘Because you have forgotten Me and have cast Me behind your back, you must bear the consequences of your indecency and prostitution.’”", "asv": "Therefore thus saith the Lord Jehovah: Because thou hast forgotten me, and cast me behind thy back, therefore bear thou also thy lewdness and thy whoredoms.", "ylt": "Therefore, thus said the Lord Jehovah: Because thou hast forgotten Me, And thou dost cast Me behind thy back, Even thou also bear thy wickedness and thy whoredoms.'", "dra": "Therefore thus saith the Lord God: Because thou hast forgotten me, and hast cast me off behind thy back, bear thou also thy wickedness, and thy fornications.", "bbe": "So this is what the Lord has said: Because you have not kept me in your memory, and because your back has been turned to me, you will even undergo the punishment of your evil designs and your loose ways.", "geneva": "Therefore thus saith the Lord God, Because thou hast forgotten me, and cast me behinde thy backe, therefore thou shalt also beare thy wickednes and thy whoredome.", "wycliffe": "Therfor the Lord God seith these thingis, For thou hast foryete me, and hast cast forth me bihynde thi bodi, bere thou also thi greet trespas and thi fornicaciouns.", "rotherham": "Therefore, Thus, saith My Lord. Yahweh, Because thou hast forgotten me, and has cast me behind thy back, Thou also thyself, bear thou thy lewdness and thine unchaste doings.", "darby": "Therefore thus saith the Lord Jehovah: Because thou hast forgotten me, and cast me behind thy back, therefore bear thou also thy lewdness and thy fornications.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because thou hast forgotten Me, and cast Me behind thy back, therefore bear thou also thy lewdness and thy harlotries.'", "acv": "Therefore thus says the lord Jehovah: Because thou have forgotten me, and cast me behind thy back, therefore thou also bear thy lewdness and thy whoredoms.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because thou hast forgotten me, and cast me behind thy back, therefore bear thou thy lewdness and thy whoredoms.", "webster": "Therefore thus saith the Lord GOD; Because thou hast forgotten me, and cast me behind thy back, therefore bear thou also thy lewdness and thy prostitutions.", "vulgate": "propterea haec dicit Dominus Deus quia oblita es mei et proiecisti me post corpus tuum tu quoque porta scelus tuum et fornicationes tuas;", "brenton": "Therefore thus saith the Lord; Because thou has forgotten me, and cast me behind thy back, therefore receive thou the reward of thine ungodliness and thy fornication."}}, {"v": 36, "ref": "23:36", "o": "וַ/יֹּ֤אמֶר יְהוָה֙ אֵלַ֔/י בֶּן אָדָ֕ם הֲ/תִשְׁפּ֥וֹט אֶֽת אָהֳלָ֖ה וְ/אֶת אָהֳלִיבָ֑ה וְ/הַגֵּ֣ד לָ/הֶ֔ן אֵ֖ת תוֹעֲבוֹתֵי/הֶֽן", "en": {"kjv": "The Lord said moreover unto me; Son of man, wilt thou judge Aholah and Aholibah? yea, declare unto them their abominations;", "web": "Yahweh said moreover to me: Son of man, will you judge Oholah and Oholibah? then declare to them their abominations.", "bsb": "Then the LORD said to me: “Son of man, will you pass judgment against Oholah and Oholibah? Then declare to them their abominations.", "asv": "Jehovah said moreover unto me: Son of man, wilt thou judge Oholah and Oholibah? then declare unto them their abominations.", "ylt": "And Jehovah saith unto me, `Son of man, Dost thou judge Aholah and Aholibah? Declare then to them their abominations.", "dra": "And the Lord spoke to me, saying: Son of man, dost thou judge Oolla, and Ooliba, and dost thou declare to them their wicked deeds?", "bbe": "Then the Lord said to me: Son of man, will you be the judge of Oholibah? then make clear to her the disgusting things she has done.", "geneva": "The Lord sayd moreouer vnto me, Sonne of man, wilt thou iudge Aholah and Aholibah? and wilt thou declare to them their abominations?", "wycliffe": "And the Lord God seide to me, and spak, Sone of man, whether thou demest Ooliba and Oolla, and tellist to hem the grete trespassis of hem?", "rotherham": "And Yahweh said unto me, Son of man Wilt thou judge Oholah and Oholibah? Then declare thou unto them their abominations.", "darby": "And Jehovah said unto me, Son of man, wilt thou judge Oholah and Oholibah? yea, declare unto them their abominations.", "twenty": "", "jps": "HaShem said moreover unto me: 'Son of man, wilt thou judge Oholah and Oholibah? then declare unto them their abominations.", "acv": "Jehovah said moreover to me, Son of man, will thou judge Oholah and Oholibah? Then declare to them their abominations.", "anderson": "", "haweis": "", "noyes": "Moreover, Jehovah said to me, Son of man, punish Aholah and Aholibah; yea, declare to them their abominations;", "webster": "The LORD said moreover to me; Son of man, wilt thou judge Aholah and Aholibah? yes, declare to them their abominations;", "vulgate": "et ait Dominus ad me dicens fili hominis numquid iudicas Oollam et Oolibam et adnuntias eis scelera earum;", "brenton": "And the Lord said to me, Son of man, wilt thou not judge Oola and Ooliba? and declare to them their iniquities?"}}, {"v": 37, "ref": "23:37", "o": "כִּ֣י נִאֵ֗פוּ וְ/דָם֙ בִּֽ/ידֵי/הֶ֔ן וְ/אֶת גִּלּֽוּלֵי/הֶ֖ן נִאֵ֑פוּ וְ/גַ֤ם אֶת בְּנֵי/הֶן֙ אֲשֶׁ֣ר יָֽלְדוּ לִ֔/י הֶעֱבִ֥ירוּ לָ/הֶ֖ם לְ/אָכְלָֽה", "en": {"kjv": "That they have committed adultery, and blood is in their hands, and with their idols have they committed adultery, and have also caused their sons, whom they bare unto me, to pass for them through the fire, to devour them.", "web": "For they have committed adultery, and blood is in their hands; and with their idols have they committed adultery; and they have also caused their sons, whom they bore to me, to pass through the fire to them to be devoured.", "bsb": "For they have committed adultery, and blood is on their hands. They have committed adultery with their idols. They have even sacrificed their children, whom they bore to Me, in the fire as food for their idols.", "asv": "For they have committed adultery, and blood is in their hands; and with their idols have they committed adultery; and they have also caused their sons, whom they bare unto me, to pass through the fire unto them to be devoured.", "ylt": "For they have committed adultery, And blood is in their hands, With their idols they committed adultery, And also their sons whom they bore to Me, They caused to pass over to them for food.", "dra": "Because they have committed adultery, and blood is in their hands, and they have committed fornication with their idols: moreover also their children, whom they bore to me, they have offered to them to be devoured.", "bbe": "For she has been false to me, and blood is on her hands, and with her images she has been untrue; and more than this, she made her sons, whom she had by me, go through the fire to them to be burned up.", "geneva": "For they haue played the whores, and blood is in their hands, and with their idoles haue they committed adulterie, and haue also caused their sonnes, whome they bare vnto me, to passe by the fire to be their meate.", "wycliffe": "For thei diden auowtrie, and blood was in the hondis of hem, and thei diden fornicacioun with her idols; ferthermore and thei offriden to tho the sones whiche thei gendriden to me, for to be deuourid.", "rotherham": "For they have committed adultery. And blood, is one their hands, Yea with their manufactured gods, have they committed adultery. And even their own children whom they bare unto me, have they set apart for them to be devoured.", "darby": "For they have committed adultery, and blood is in their hands; and with their idols have they committed adultery, and have also passed over unto them their children, whom they bore unto me, to be devoured.", "twenty": "", "jps": "For they have committed adultery, and blood is in their hands, and with their idols have they committed adultery; and their sons, whom they bore unto Me, they have also set apart unto them to be devoured.", "acv": "For they have committed adultery, and blood is in their hands. And with their idols they have committed adultery. And they have also caused their sons, whom they bore to me, to pass through the fire for them to be devoured.", "anderson": "", "haweis": "", "noyes": "that they have committed adultery, and blood is upon their hands, and that with their idols they have committed adultery, and have also caused their sons, whom they bore to me, to pass through the fire to them for food.", "webster": "That they have committed adultery, and blood [is] in their hands, and with their idols have they committed adultery, and have also caused their sons, whom they bore to me, to pass for them through [the fire], to devour [them].", "vulgate": "quia adulterae sunt et sanguis in manibus earum et cum idolis suis fornicatae sunt insuper et filios suos quos genuerunt mihi obtulerunt eis ad devorandum;", "brenton": "For they have committed adultery, and blood was in their hands, they committed adultery with their devices, and they passed through the fire to them their children which they bore to me."}}, {"v": 38, "ref": "23:38", "o": "ע֥וֹד זֹ֖את עָ֣שׂוּ לִ֑/י טִמְּא֤וּ אֶת מִקְדָּשִׁ/י֙ בַּ/יּ֣וֹם הַ/ה֔וּא וְ/אֶת שַׁבְּתוֹתַ֖/י חִלֵּֽלוּ", "en": {"kjv": "Moreover this they have done unto me: they have defiled my sanctuary in the same day, and have profaned my sabbaths.", "web": "Moreover this they have done to me: they have defiled my sanctuary in the same day, and have profaned my Sabbaths.", "bsb": "They have also done this to Me: On that very same day, they defiled My sanctuary and profaned My Sabbaths.", "asv": "Moreover this they have done unto me: they have defiled my sanctuary in the same day, and have profaned my sabbaths.", "ylt": "Again, this they have done to Me, They defiled My sanctuary in that day, And My sabbaths they have polluted.", "dra": "Yea, and they have done this to me. They polluted my sanctuary on the same day, and profaned my sabbaths.", "bbe": "Further, this is what she has done to me: she has made my holy place unclean and has made my Sabbaths unclean.", "geneva": "Moreouer, thus haue they done vnto me: they haue defiled my Sanctuarie in the same day, and haue prophaned my Sabbaths.", "wycliffe": "But also thei diden this to me, thei defouleden my seyntuarie in that dai, and maden vnhooli my sabatis.", "rotherham": "Yet more, this, have they done to me, They have defiled my sanctuary, on the same day, And my sabbaths, have they profaned.", "darby": "Moreover this have they done unto me: in the same day have they defiled my sanctuary and profaned my sabbaths.", "twenty": "", "jps": "Moreover this they have done unto Me: they have defiled My sanctuary in the same day, and have profaned My sabbaths.", "acv": "Moreover they have done this to me: They have defiled my sanctuary in the same day, and have profaned my sabbaths.", "anderson": "", "haweis": "", "noyes": "This also have they done to me: they have defiled my sanctuary in the same day, and have profaned my sabbaths.", "webster": "Moreover this they have done to me: they have defiled my sanctuary in the same day, and have profaned my sabbaths.", "vulgate": "sed et hoc fecerunt mihi polluerunt sanctuarium meum in die illa et sabbata mea profanaverunt;", "brenton": "So long too as they did these things to me, they defiled my sanctuary, and profaned my sabbaths."}}, {"v": 39, "ref": "23:39", "o": "וּֽ/בְ/שַׁחֲטָ֤/ם אֶת בְּנֵי/הֶם֙ לְ/גִלּ֣וּלֵי/הֶ֔ם וַ/יָּבֹ֧אוּ אֶל מִקְדָּשִׁ֛/י בַּ/יּ֥וֹם הַ/ה֖וּא לְ/חַלְּל֑/וֹ וְ/הִנֵּה כֹ֥ה עָשׂ֖וּ בְּ/ת֥וֹךְ בֵּיתִֽ/י", "en": {"kjv": "For when they had slain their children to their idols, then they came the same day into my sanctuary to profane it; and, lo, thus have they done in the midst of mine house.", "web": "For when they had slain their children to their idols, then they came the same day into my sanctuary to profane it; and behold, thus have they done in the midst of my house.", "bsb": "On the very day they slaughtered their children for their idols, they entered My sanctuary to profane it. Yes, they did this inside My house.", "asv": "For when they had slain their children to their idols, then they came the same day into my sanctuary to profane it; and, lo, thus have they done in the midst of my house.", "ylt": "And in their slaughtering their sons to their idols They also come in unto My sanctuary in that day to pollute it, And lo, thus they have done in the midst of My house,", "dra": "And when they sacrificed their children to their idols, and went into my sanctuary the same day to profane it: they did these things even in the midst of my house.", "bbe": "For when she had made an offering of her children to her images, she came into my holy place to make it unclean; see, this is what she has done inside my house.", "geneva": "For when they had slaine their children to their idoles, they came the same day into my Sanctuarie to defile it: and loe, thus haue they done in the middes of mine house.", "wycliffe": "And whanne thei sacrifisiden her sones to her idols, and entriden in to my seyntuarie in that dai, that thei schulden defoule it, thei diden also these thingis in the myddis of myn hous.", "rotherham": "Yea when they had slaughtered their children to their manufactured gods, then entered they into my sanctuary, on the same day, to profane it,- And lo! thus have they done in the midst of mine own house.", "darby": "For when they had slaughtered their children unto their idols, they came the same day into my sanctuary to profane it; and behold, thus have they done in the midst of my house.", "twenty": "", "jps": "For when they had slain their children to their idols, then they came the same day into My sanctuary to profane it; and, lo, thus have they done in the midst of My house.", "acv": "For when they had slain their sons to their idols, then they came the same day into my sanctuary to profane it, and, lo, thus they have done in the midst of my house.", "anderson": "", "haweis": "", "noyes": "For when they had slain their children to their idols, then they came into my sanctuary the same day to profane it; behold, thus have they done in my house.", "webster": "For when they had slain their children to their idols, then they came the same day into my sanctuary to profane it; and lo, thus have they done in the midst of my house.", "vulgate": "cumque immolarent filios suos idolis suis et ingrederentur sanctuarium meum in die illa ut polluerent illud etiam haec fecerunt in medio domus meae;", "brenton": "And when they sacrificed their children to their idols, they also went into my sanctuary to profane it: and whereas they did thus in the midst of my house;"}}, {"v": 40, "ref": "23:40", "o": "וְ/אַ֗ף כִּ֤י תִשְׁלַ֨חְנָה֙ לַֽ/אֲנָשִׁ֔ים בָּאִ֖ים מִ/מֶּרְחָ֑ק אֲשֶׁ֨ר מַלְאָ֜ךְ שָׁל֤וּחַ אֲלֵי/הֶם֙ וְ/הִנֵּה בָ֔אוּ לַ/אֲשֶׁ֥ר רָחַ֛צְתְּ כָּחַ֥לְתְּ עֵינַ֖יִ/ךְ וְ/עָ֥דִית עֶֽדִי", "en": {"kjv": "And furthermore, that ye have sent for men to come from far, unto whom a messenger was sent; and, lo, they came: for whom thou didst wash thyself, paintedst thy eyes, and deckedst thyself with ornaments,", "web": "Furthermore you have sent for men who come from far, to whom a messenger was sent, and behold, they came; for whom you did wash yourself, paint your eyes, and decorate yourself with ornaments,", "bsb": "Furthermore, you sisters sent messengers for men who came from afar; and behold, when they arrived, you bathed for them, painted your eyes, and adorned yourself with jewelry.", "asv": "And furthermore ye have sent for men that come from far, unto whom a messenger was sent, and, lo, they came; for whom thou didst wash thyself, paint thine eyes, and deck thyself with ornaments,", "ylt": "And also that they send to men coming from afar, Unto whom a messenger is sent, And lo, they have come in for whom thou hast washed, Painted thine eyes, and put on adornment.", "dra": "They sent for men coming from afar, to whom they had sent a messenger: and behold they came: for whom thou didst wash thyself, and didst paint thy eyes, and wast adorned with women's ornaments.", "bbe": "And she even sent for men to come from far away, to whom a servant was sent, and they came: for whom she was washing her body and painting her eyes and making herself fair with ornaments.", "geneva": "And howe much more is it that they sent for men to come from farre vnto whom a messenger was sent, and loe, they came? for whome thou diddest wash thy selfe, and paintedst thine eyes, and deckedst thee with ornaments,", "wycliffe": "Thei senten to men comyng fro fer, to whiche thei hadden sent messangeris. Therfor lo! thei camen, to whiche thou waischidist thee, and anoyntidist thin iyen with oynement of wymmen, and thou were ourned with wymmens atier.", "rotherham": "Yea verily, that ye must needs send for men, ready to come in from afar, in that, a messenger, was sent unto them and lo! they came, For whom thou didst bathe thyself Paint thine eyes And deck thyself with ornaments.", "darby": "And furthermore, they sent for men to come from far, unto whom a messenger was sent; and behold, they came: for whom thou didst wash thyself, paintedst thine eyes, and deckedst thyself with ornaments;", "twenty": "", "jps": "And furthermore ye have sent for men that come from far; unto whom a messenger was sent, and, lo, they came; for whom thou didst wash thyself, paint thine eyes, and deck thyself with ornaments;", "acv": "And furthermore ye have sent for men who come from far, to whom a messenger was sent. And, lo, they came, for whom thou washed thyself, painted thine eyes, and decked thyself with ornaments,", "anderson": "", "haweis": "", "noyes": "Yea, ye sent for men to come from afar; messengers were sent to them, and behold, they came; for them didst thou wash thyself, and paint thine eyes, and deck thyself with ornaments.", "webster": "And furthermore, that ye have sent for men to come from far, to whom a messenger [was] sent; and lo, they came: for whom thou didst wash thyself, paint thy eyes, and deck thyself with ornaments,", "vulgate": "miserunt ad viros venientes de longe ad quos nuntium miserant itaque ecce venerunt quibus te lavisti et circumlevisti stibio oculos tuos et ornata es mundo muliebri;", "brenton": "and whereas they did thus to the men that came from afar, to whom they sent messengers, and as soon as they came, immediately thou didst wash thyself, and didst paint thine eyes and adorn thyself with ornaments,"}}, {"v": 41, "ref": "23:41", "o": "וְ/יָשַׁבְתְּ֙ עַל מִטָּ֣ה כְבוּדָּ֔ה וְ/שֻׁלְחָ֥ן עָר֖וּךְ לְ/פָנֶ֑י/הָ וּ/קְטָרְתִּ֥/י וְ/שַׁמְנִ֖/י שַׂ֥מְתְּ עָלֶֽי/הָ", "en": {"kjv": "And satest upon a stately bed, and a table prepared before it, whereupon thou hast set mine incense and mine oil.", "web": "and sit on a stately bed, with a table prepared before it, whereupon you set my incense and my oil.", "bsb": "You sat on a couch of luxury with a table spread before it, on which you had set My incense and My oil,", "asv": "and sit upon a stately bed, with a table prepared before it, whereupon thou didst set mine incense and mine oil.", "ylt": "And thou hast sat on a couch of honour, And a table arrayed before it, And My perfume and My oil placed on it.", "dra": "Thou sattest on a very fine bed, and a table was decked before thee: whereupon thou didst set my incense, and my ointment.", "bbe": "And she took her seat on a great bed, with a table put ready before it on which she put my perfume and my oil.", "geneva": "And satest vpon a costly bed, and a table prepared before it, whereupon thou hast set mine incense and mine oyle.", "wycliffe": "Thou satist in a ful fair bed, and a boord was ourned bifor thee; thou settidist myn encense and myn oynement on it.", "rotherham": "Then satest thou upon a glorious couch With a table prepared before it,— And mine incense and mine oil, didst thou set thereon.", "darby": "and satest upon a stately bed, with a table prepared before it, whereupon thou hadst set mine incense and mine oil.", "twenty": "", "jps": "and sattest upon a stately bed, with a table prepared before it, whereupon thou didst set Mine incense and Mine oil.", "acv": "and sat upon a stately bed, with a table prepared before it, whereupon thou did set my incense and my oil.", "anderson": "", "haweis": "", "noyes": "And thou didst seat thyself upon a stately bed before which a table was prepared, and thereon didst thou set my incense and my oil.", "webster": "And sattest upon a stately bed and a table prepared before it, upon which thou hast set my incense and my oil.", "vulgate": "sedisti in lecto pulcherrimo et mensa ordinata est ante te thymiama meum et unguentum meum posuisti super eam;", "brenton": "and satest on a prepared bed, and before it there was a table set out, and as for mine incense and mine oil, they rejoiced in them,"}}, {"v": 42, "ref": "23:42", "o": "וְ/ק֣וֹל הָמוֹן֮ שָׁלֵ֣ו בָ/הּ֒ וְ/אֶל אֲנָשִׁים֙ מֵ/רֹ֣ב אָדָ֔ם מוּבָאִ֥ים סובאים סָבָאִ֖ים מִ/מִּדְבָּ֑ר וַֽ/יִּתְּנ֤וּ צְמִידִים֙ אֶל יְדֵי/הֶ֔ן וַ/עֲטֶ֥רֶת תִּפְאֶ֖רֶת עַל רָאשֵׁי/הֶֽן", "en": {"kjv": "And a voice of a multitude being at ease was with her: and with the men of the common sort were brought Sabeans from the wilderness, which put bracelets upon their hands, and beautiful crowns upon their heads.", "web": "The voice of a multitude being at ease was with her: and with men of the common sort were brought drunkards from the wilderness; and they put bracelets on their hands, and beautiful crowns on their heads.", "bsb": "accompanied by the sound of a carefree crowd. Drunkards were brought in from the desert along with men from the rabble, who put bracelets on your wrists and beautiful crowns on your head.", "asv": "And the voice of a multitude being at ease was with her: and with men of the common sort were brought drunkards from the wilderness; and they put bracelets upon the hands of them twain, and beautiful crowns upon their heads.", "ylt": "And the voice of a multitude at ease is with her, And unto men of the common people are brought in Sabeans from the wilderness, And they put bracelets on their hands, And a beauteous crown on their heads.", "dra": "And there was in her the voice of a multitude rejoicing: and to some that were brought of the multitude of men, and that came from the desert, they put bracelets on their hands, and beautiful crowns on their heads.", "bbe": "... and they put jewels on her hands and beautiful crowns on her head.", "geneva": "And a voyce of a multitude being at ease, was with her: and with the men to make the company great were brought men of Saba from the wildernes, which put bracelets vpon their hands, and beautifull crownes vpon their heads.", "wycliffe": "And a vois of multitude makynge ful out ioye was ther ynne; and in men that weren brouyt of the multitude of men, and camen fro desert, thei settiden bies in the hondis of hem, and faire corouns on the heedis of hem.", "rotherham": "The noise of careless throng also, was with her, And besides men out of the mass of mankind, there were brought in drunkards, out of the desert; And they put bracelets upon the hands of both women, And crowns of adorning upon their heads.", "darby": "And the voice of a multitude living carelessly was with her; and with people of the common sort were brought Sabeans from the wilderness, and they put bracelets upon their hands, and a beautiful crown upon their heads.", "twenty": "", "jps": "And the voice of a multitude being at ease was therein; and for the sake of men, they were so many, brought drunken from the wilderness, they put bracelets upon their hands, and beautiful crowns upon their heads.", "acv": "And the voice of a multitude being at ease was with her. And with men of the common sort, were brought drunkards from the wilderness, and they put bracelets upon the hands of those two women, and beautiful crowns upon their heads.", "anderson": "", "haweis": "", "noyes": "Also the voice of a multitude at ease was with her; and together with men from the common multitude were brought deep-drinkers from the desert, who put bracelets upon their hands, and beautiful crowns upon their heads.", "webster": "And a voice of a multitude being at ease [was] with her: and with the men of the common sort [were] brought Sabeans from the wilderness, who put bracelets upon their hands, and beautiful crowns upon their heads.", "vulgate": "et vox multitudinis exultantis erat in ea et in viris qui de multitudine hominum adducebantur et veniebant de deserto posuerunt armillas in manibus eorum et coronas speciosas in capitibus eorum;", "brenton": "and they raised a sound of music, and that with men coming from the wilderness out of a multitude of men, and they put bracelets on their hands, and a crown of glory on their heads;"}}, {"v": 43, "ref": "23:43", "o": "וָ/אֹמַ֕ר לַ/בָּלָ֖ה נִֽאוּפִ֑ים עת עַתָּ֛ה יזנה יִזְנ֥וּ תַזְנוּתֶ֖/הָ וָ/הִֽיא", "en": {"kjv": "Then said I unto her that was old in adulteries, Will they now commit whoredoms with her, and she with them?", "web": "Then I said of her who was old in adulteries, Now they will play the prostitute with her, and she with them.", "bsb": "Then I said of her who had grown old in adulteries: ‘Now let them use her as a prostitute, for that is all she is!’", "asv": "Then said I of her that was old in adulteries, Now will they play the harlot with her, and she with them.", "ylt": "And I say of the worn-out one in adulteries, Now they commit her whoredoms--she also!", "dra": "And I said to her that was worn out in her adulteries: Now will this woman still continue in her fornication.", "bbe": "Then I said ... now she will go on with her loose ways.", "geneva": "Then I sayd vnto her, that was olde in adulteries, Now shall she and her fornications come to an end.", "wycliffe": "And Y seide to hir, that was defoulid in auoutries, Now also this schal do fornycacioun in hir fornicacioun.", "rotherham": "Then said I of her that was worn out with adulteries, Will they now join in her unchaste doings even hers?", "darby": "And I said of her that was old in adulteries, Will she now commit her fornications, even she.", "twenty": "", "jps": "Then said I of her that was worn out by adulteries: Still they commit harlotries with her, even her.", "acv": "Then I said of her who was old in adulteries, Now they will play the harlot with her, and she with them.", "anderson": "", "haweis": "", "noyes": "Then said I concerning her that was worn out with adulteries, Will they now commit whoredoms with her, even with her?", "webster": "Then said I to [her that was] old in adulteries, Will they now commit lewd deeds with her, and she [with them]?", "vulgate": "et dixi ei quae adtrita est in adulteriis nunc fornicabitur in fornicatione sua etiam haec;", "brenton": "Therefore I said, Do they not commit adultery with these? and has she also gone a-whoring after the manner of a harlot?"}}, {"v": 44, "ref": "23:44", "o": "וַ/יָּב֣וֹא אֵלֶ֔י/הָ כְּ/ב֖וֹא אֶל אִשָּׁ֣ה זוֹנָ֑ה כֵּ֣ן בָּ֗אוּ אֶֽל אָֽהֳלָה֙ וְ/אֶל אָ֣הֳלִיבָ֔ה אִשֹּׁ֖ת הַ/זִּמָּֽה", "en": {"kjv": "Yet they went in unto her, as they go in unto a woman that playeth the harlot: so went they in unto Aholah and unto Aholibah, the lewd women.", "web": "They went in to her, as they go in to a prostitute: so went they in to Oholah and to Oholibah, the lewd women.", "bsb": "And they slept with her as with a prostitute; they slept with Oholah and Oholibah, those lewd women.", "asv": "And they went in unto her, as they go in unto a harlot: so went they in unto Oholah and unto Oholibah, the lewd women.", "ylt": "And they come in unto her, As the coming in unto a whorish woman, So they have come in unto Aholah, And unto Aholibah--the wicked women.", "dra": "And they went in to her, as to a harlot: so went they in unto Oolla, and Ooliba, wicked women.", "bbe": "And they went in to her, as men go to a loose woman: so they went in to Oholibah, the loose woman.", "geneva": "And they went in vnto her as they goe to a common harlot: so went they to Aholah and Aholibah the wicked women.", "wycliffe": "And thei entriden to hir; as to a womman, an hoore, so thei entriden to Oolla and to Ooliba, cursid wymmen.", "rotherham": "Yet came they in unto her, as men go in unto a woman that is a harlot,— So, came they in unto Oholah, and unto Oholibah—the lewd women!", "darby": "And they went in unto her, as they go in unto a whorish woman: so went they in unto Oholah and unto Oholibah the lewd women.", "twenty": "", "jps": "For every one went in unto her, as men go in unto a harlot; so went they in unto Oholah and unto Oholibah, the lewd women.", "acv": "And they went in to her, as they go in to a harlot. So they went in to Oholah and to Oholibah, the lewd women.", "anderson": "", "haweis": "", "noyes": "They went in to her, as men go to a harlot; so went they in to Aholah and to Aholibah, the lewd women.", "webster": "Yet they went in to her, as they go in to a woman that playeth the harlot: so they went in to Aholah and to Aholibah, the lewd women.", "vulgate": "et ingressi sunt ad eam quasi ad mulierem meretricem sic ingrediebantur ad Oollam et ad Oolibam mulieres nefarias;", "brenton": "And they went in to her, as men go in to a harlot; so they went in to Oola and to Ooliba to work iniquity."}}, {"v": 45, "ref": "23:45", "o": "וַ/אֲנָשִׁ֣ים צַדִּיקִ֗ם הֵ֚מָּה יִשְׁפְּט֣וּ אֽוֹתְ/הֶ֔ם מִשְׁפַּט֙ נֹֽאֲפ֔וֹת וּ/מִשְׁפַּ֖ט שֹׁפְכ֣וֹת דָּ֑ם כִּ֤י נֹֽאֲפֹת֙ הֵ֔נָּה וְ/דָ֖ם בִּֽ/ידֵי/הֶֽן", "en": {"kjv": "And the righteous men, they shall judge them after the manner of adulteresses, and after the manner of women that shed blood; because they are adulteresses, and blood is in their hands.", "web": "Righteous men, they shall judge them with the judgment of adulteresses, and with the judgment of women who shed blood; because they are adulteresses, and blood is in their hands.", "bsb": "But righteous men will sentence them to the punishment of those who commit adultery and bloodshed, because they are adulteresses with blood on their hands.", "asv": "And righteous men, they shall judge them with the judgment of adulteresses, and with the judgment of women that shed blood; because they are adulteresses, and blood is in their hands.", "ylt": "As to righteous men, they judge them with the judgment of adulteresses, And the judgment of women shedding blood, For they are adulteresses, And blood is in their hands.", "dra": "They therefore are just men: these shall judge them as adulteresses are judged, and as shedders of blood are judged: because they are adulteresses, and blood is in their hands.", "bbe": "And upright men will be her judges, judging her as false wives and women who take lives are judged; because she has been untrue to me and blood is on her hands.", "geneva": "And ye righteous men they shall iudge them, after the maner of harlots, and after the maner of murtherers: for they are harlots, and blood is in their hands.", "wycliffe": "Therfor these men ben iust, these schulen deme thilke wymmen bi the doom of auoutressis, and bi the doom of hem that scheden out blood; for thei ben auoutressis, and blood is in the hondis of hem, and thei diden fornicacioun with her idols.", "rotherham": "But righteous men, they, shall judge them, With the judgment of adulteresses, and With the judgment of women that shed blood,— Because adulteresses, they are And blood, is on their hands.", "darby": "And righteous men, they shall judge them with the judgment of adulteresses, and with the judgment of women that shed blood; for they are adulteresses, and blood is in their hands.", "twenty": "", "jps": "But righteous men, they shall judge them as adulteresses are judged, and as women that shed blood are judged; because they are adulteresses, and blood is in their hands.", "acv": "And righteous men, they shall judge them with the judgment of adulteresses, and with the judgment of women who shed blood, because they are adulteresses, and blood is on their hands.", "anderson": "", "haweis": "", "noyes": "But righteous men shall judge them, as adulteresses are judged, and as women that shed blood are judged; for they are adulteresses, and blood is upon their hands.", "webster": "And the righteous men, they shall judge them after the manner of adulteresses, and after the manner of women that shed blood; because they [are] adulteresses, and blood [is] in their hands.", "vulgate": "viri ergo iusti sunt hii iudicabunt eas iudicio adulterarum et iudicio effundentium sanguinem quia adulterae sunt et sanguis in manibus earum;", "brenton": "And they are just men, and shall take vengeance on them with the judgment of an adulteress and the judgment of blood: for they are adulteresses, and blood is in their hands."}}, {"v": 46, "ref": "23:46", "o": "כִּ֛י כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הַעֲלֵ֤ה עֲלֵי/הֶם֙ קָהָ֔ל וְ/נָתֹ֥ן אֶתְ/הֶ֖ן לְ/זַעֲוָ֥ה וְ/לָ/בַֽז", "en": {"kjv": "For thus saith the Lord God; I will bring up a company upon them, and will give them to be removed and spoiled.", "web": "For thus says the Lord Yahweh: I will bring up a company against them, and will give them to be tossed back and forth and robbed.", "bsb": "This is what the Lord GOD says: ‘Bring a mob against them and consign them to terror and plunder.", "asv": "For thus saith the Lord Jehovah: I will bring up a company against them, and will give them to be tossed to and fro and robbed.", "ylt": "For thus said the Lord Jehovah: Bring up against them an assembly, And give them to trembling and to spoiling.", "dra": "For thus saith the Lord God: Bring a multitude upon them, and deliver them over to tumult and rapine:", "bbe": "For this is what the Lord has said: I will make a great meeting of the people come together against her, and will send on her shaking fear and take everything from her.", "geneva": "Wherefore thus sayth the Lord God, I will bring a multitude vpon them, and will giue them vnto the tumult, and to the spoyle,", "wycliffe": "For the Lord God seith these thingis, Bringe thou multitudis to hem, and yyue thou hem in to noise, and in to raueyn;", "rotherham": "For thus, saith My Lord. Yahweh,- There shall be brought up against them a gathered host, Then shall they be delivered up. for a terror and for a prey,", "darby": "For thus saith the Lord Jehovah: I will bring up an assemblage against them, and will give them to be driven hither and thither and spoiled.", "twenty": "", "jps": "For thus saith the L-rd GOD: An assembly shall be brought up against them, and they shall be made a horror and a spoil.", "acv": "For thus says the lord Jehovah: I will bring up a company against them, and will give them to be tossed to and fro and robbed.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: I will bring a great company against them, and will give them up to be harassed and spoiled,", "webster": "For thus saith the Lord GOD; I will bring up a company upon them, and will give them to be removed and plundered.", "vulgate": "haec enim dicit Dominus Deus adduc ad eas multitudinem et trade eas in tumultum et in rapinam;", "brenton": "Thus saith the Lord God, Bring up a multitude upon them, and send trouble and plunder into the midst of them."}}, {"v": 47, "ref": "23:47", "o": "וְ/רָגְמ֨וּ עֲלֵי/הֶ֥ן אֶ֨בֶן֙ קָהָ֔ל וּ/בָרֵ֥א אוֹתְ/הֶ֖ן בְּ/חַרְבוֹתָ֑/ם בְּנֵי/הֶ֤ם וּ/בְנֽוֹתֵי/הֶם֙ יַהֲרֹ֔גוּ וּ/בָתֵּי/הֶ֖ן בָּ/אֵ֥שׁ יִשְׂרֹֽפוּ", "en": {"kjv": "And the company shall stone them with stones, and dispatch them with their swords; they shall slay their sons and their daughters, and burn up their houses with fire.", "web": "The company shall stone them with stones, and dispatch them with their swords; they shall kill their sons and their daughters, and burn up their houses with fire.", "bsb": "The mob will stone them and cut them down with their swords. They will kill their sons and daughters and burn down their houses.", "asv": "And the company shall stone them with stones, and despatch them with their swords; they shall slay their sons and their daughters, and burn up their houses with fire.", "ylt": "And they have cast at them the stone of the assembly, And cut them with their swords, Their sons and their daughters they do slay, And their houses with fire they burn.", "dra": "And let the people stone them with stone, and let them be stabbed with their swords: they shall kill their sons and daughters, and their houses they shall burn with fire.", "bbe": "And the meeting, after stoning her with stones, will put an end to her with their swords; they will put her sons and daughters to death and have her house burned up with fire.", "geneva": "And the multitude shall stone them with stones, and cut them with their swordes: they shall slay their sonnes, and their daughters, and burne vp their houses with fire.", "wycliffe": "and be thei stoonyd with the stoonys of puplis, and be thei stikid togidere with the swerdis of hem. Thei schulen sle the sones and the douytris of hem, and thei schulen brenne with fier the housis of hem.", "rotherham": "Yea a gathered host shall stone them with stones, and dispatch them with their swords, Their sons and their daughters, shall they slay, And their houses—in the fire, shall they consume.", "darby": "And the assemblage shall stone them with stones, and despatch them with their swords; they shall kill their sons and their daughters, and burn their houses with fire.", "twenty": "", "jps": "And the assembly shall stone them with stones, and despatch them with their swords; they shall slay their sons and their daughters, and burn up their houses with fire.", "acv": "And the company shall stone them with stones, and dispatch them with their swords. They shall kill their sons and their daughters, and burn up their houses with fire.", "anderson": "", "haweis": "", "noyes": "and the company shall stone them with stones, and cut them in pieces with their swords; they shall slay their sons and their daughters, and burn their houses with fire.", "webster": "And the company shall stone them with stones, and dispatch them with their swords; they shall slay their sons and their daughters, and burn their houses with fire.", "vulgate": "et lapidentur lapidibus populorum et confodiantur gladiis eorum filios et filias earum interficient et domos earum igne succendent;", "brenton": "And stone them with the stones of a multitude, and pierce them with their swords: they shall slay their sons and their daughters, and shall burn up their houses."}}, {"v": 48, "ref": "23:48", "o": "וְ/הִשְׁבַּתִּ֥י זִמָּ֖ה מִן הָ/אָ֑רֶץ וְ/נִֽוַּסְּרוּ֙ כָּל הַ/נָּשִׁ֔ים וְ/לֹ֥א תַעֲשֶׂ֖ינָה כְּ/זִמַּתְ/כֶֽנָה", "en": {"kjv": "Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.", "web": "Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.", "bsb": "So I will put an end to indecency in the land, and all the women will be admonished not to imitate your behavior.", "asv": "Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.", "ylt": "And I have caused wickedness to cease from the land, And instructed have been all the women, And they do not according to your wickedness.", "dra": "And I will take away wickedness out of the land: and all women shall learn, not to do according to the wickedness of them.", "bbe": "And I will put an end to evil in all the land, teaching all women not to do as you have done.", "geneva": "Thus will I cause wickednesse to cease out of the land, that all women may be taught not to doe after your wickednesse.", "wycliffe": "And Y schal do awei greet trespas fro the lond; and alle wymmen schulen lerne, that thei do not aftir the greet trespas of hem.", "rotherham": "So will I make an end of lewdness out of the land,- And all women shall be disciplined, and shall not do according to your lewdness.", "darby": "And I will cause lewdness to cease out of the land, and all women shall receive instruction and shall not do according to your lewdness.", "twenty": "", "jps": "Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.", "acv": "Thus I will cause lewdness to cease out of the land, that all women may be taught not to do according to your lewdness.", "anderson": "", "haweis": "", "noyes": "Thus will I cause lewdness to cease out of the land, that all women may take warning, and not follow them in their lewdness.", "webster": "Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.", "vulgate": "et auferam scelus de terra et discent omnes mulieres ne faciant secundum scelus earum;", "brenton": "And I will remove ungodliness out of the land, and all the women shall be instructed, and shall not do according to their ungodliness."}}, {"v": 49, "ref": "23:49", "o": "וְ/נָתְנ֤וּ זִמַּתְ/כֶ֨נָה֙ עֲלֵי/כֶ֔ן וַ/חֲטָאֵ֥י גִלּוּלֵי/כֶ֖ן תִּשֶּׂ֑אינָה וִ/ידַעְתֶּ֕ם כִּ֥י אֲנִ֖י אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols: and ye shall know that I am the Lord God.", "web": "They shall recompense your lewdness on you, and you shall bear the sins of your idols; and you shall know that I am the Lord Yahweh.", "bsb": "They will repay you for your indecency, and you will bear the consequences of your sins of idolatry. Then you will know that I am the Lord GOD.’”", "asv": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols; and ye shall know that I am the Lord Jehovah.", "ylt": "And they have put your wickedness on you, And the sins of your idols ye bear, And ye have known that I am the Lord Jehovah!", "dra": "And they shall render your wickedness upon you, and you shall bear the sins of your idols: and you shall know that I am the Lord God.", "bbe": "And I will send on you the punishment of your evil ways, and you will be rewarded for your sins with your images: and you will be certain that I am the Lord.", "geneva": "And they shall laye your wickednesse vpon you, and ye shall beare the sinnes of your idoles, and ye shall knowe that I am the Lord God.", "wycliffe": "And thei schulen yyue youre grete trespas on you; and ye schulen bere the synnes of youre idols, and ye schulen wite, that Y am the Lord God.", "rotherham": "Yea the judges Shall set your lewdness upon you, And your sins with manufactured gods, shall ye bear; So shall ye know that, I, am The Lord Yahweh.", "darby": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols; and ye shall know that I [am] the Lord Jehovah.", "twenty": "", "jps": "And your lewdness shall be recompensed upon you, and ye shall bear the sins of your idols; and ye shall know that I am the L-rd GOD.'", "acv": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols. And ye shall know that I am the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols; that ye may know that I am the Lord Jehovah.", "webster": "And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols: and ye shall know that I [am] the Lord GOD.", "vulgate": "et dabunt scelus vestrum super vos et peccata idolorum vestrorum portabitis et scietis quia ego Dominus Deus;", "brenton": "And your ungodliness shall be recompensed upon you, and ye shall bear the guilt of your devices: and ye shall know that I am the Lord."}}]}, {"c": 24, "verses": [{"v": 1, "ref": "24:1", "o": "וַ/יְהִי֩ דְבַר יְהוָ֨ה אֵלַ֜/י בַּ/שָּׁנָ֤ה הַ/תְּשִׁיעִית֙ בַּ/חֹ֣דֶשׁ הָ/עֲשִׂירִ֔י בֶּ/עָשׂ֥וֹר לַ/חֹ֖דֶשׁ לֵ/אמֹֽר", "en": {"kjv": "Again in the ninth year, in the tenth month, in the tenth day of the month, the word of the Lord came unto me, saying,", "web": "Again, in the ninth year, in the tenth month, in the tenth day of the month, Yahweh’s word came to me, saying,", "bsb": "In the ninth year, on the tenth day of the tenth month, the word of the LORD came to me, saying,", "asv": "Again, in the ninth year, in the tenth month, in the tenthdayof the month, the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, in the ninth year, in the tenth month, in the tenth of the month, saying,", "dra": "And the word of the Lord came to me in the ninth year, in the tenth month, the tenth day of the month, saying:", "bbe": "And the word of the Lord came to me in the ninth year, in the tenth month, on the tenth day of the month, saying,", "geneva": "Again in the ninth yeere, in the tenth moneth, in the tenth day of the moneth, came the worde of the Lord vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, in the nynthe yeer, and in the tenthe monethe, in the tenthe dai of the monethe,", "rotherham": "And the word of Yahweh came unto me. in the ninth year in the tenth month, on the tenth of the month, saying:", "darby": "And in the ninth year, in the tenth month, on the tenth of the month, the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me in the ninth year, in the tenth month, in the tenth day of the month, saying:", "acv": "Again, in the ninth year, in the tenth month, in the tenth day of the month, the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me in the ninth year, in the tenth month, in the tenth day of the month, and said:", "webster": "Again in the ninth year, in the tenth month, in the tenth [day] of the month, the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me in anno nono in mense decimo decima mensis dicens;", "brenton": "And the word of the Lord came to me, in the ninth year, in the tenth month, on the tenth day of the month, saying,"}}, {"v": 2, "ref": "24:2", "o": "בֶּן אָדָ֗ם כתוב כְּתָב לְ/ךָ֙ אֶת שֵׁ֣ם הַ/יּ֔וֹם אֶת עֶ֖צֶם הַ/יּ֣וֹם הַ/זֶּ֑ה סָמַ֤ךְ מֶֽלֶךְ בָּבֶל֙ אֶל יְר֣וּשָׁלִַ֔ם בְּ/עֶ֖צֶם הַ/יּ֥וֹם הַ/זֶּֽה", "en": {"kjv": "Son of man, write thee the name of the day, even of this same day: the king of Babylon set himself against Jerusalem this same day.", "web": "Son of man, write the name of the day, this same day. The king of Babylon drew close to Jerusalem this same day.", "bsb": "“Son of man, write down today’s date, for on this very day the king of Babylon has laid siege to Jerusalem.", "asv": "Son of man, write thee the name of the day, even of this selfsame day: the king of Babylon drew close unto Jerusalem this selfsame day.", "ylt": "`Son of man, write for thee the name of the day--this self-same day leaned hath the king of Babylon toward Jerusalem in this self-same day--", "dra": "Son of man, write thee the name of this day, on which the king of Babylon hath set himself against Jerusalem to day.", "bbe": "Son of man, put down in writing this very day: The king of Babylon let loose the weight of his attack against Jerusalem on this very day.", "geneva": "Sonne of man, write thee the name of the day, euen of this same day: for the King of Babel set himselfe against Ierusalem this same day.", "wycliffe": "and he seide, Thou, sone of man, write to thee the name of this dai, in which the king of Babiloyne is confermed ayens Jerusalem to dai.", "rotherham": "Son of man. Write thee the name of the day, this selfsame day,—the king of Babylon cast himself against Jerusalem, on this selfsame day.", "darby": "Son of man, write thee the name of the day, of this selfsame day: on this selfsame day the king of Babylon draws near to Jerusalem.", "twenty": "", "jps": "'Son of man, write thee the name of the day, even of this selfsame day; this selfsame day the king of Babylon hath invested Jerusalem.", "acv": "Son of man, write thee the name of the day, even of this selfsame day; the king of Babylon drew close to Jerusalem this selfsame day.", "anderson": "", "haweis": "", "noyes": "Son of man, write the name of the day, even of this same day. The king of Babylon draweth near to Jerusalem this same day.", "webster": "Son of man, Write for thee the name of the day, [even] of this same day: the king of Babylon set himself against Jerusalem this same day.", "vulgate": "fili hominis scribe tibi nomen diei huius in qua confirmatus est rex Babylonis adversum Hierusalem hodie;", "brenton": "Son of man, write for thyself daily from this day, on which the king of Babylon set himself against Jerusalem, even from this day."}}, {"v": 3, "ref": "24:3", "o": "וּ/מְשֹׁ֤ל אֶל בֵּית הַ/מֶּ֨רִי֙ מָשָׁ֔ל וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה שְׁפֹ֤ת הַ/סִּיר֙ שְׁפֹ֔ת וְ/גַם יְצֹ֥ק בּ֖/וֹ מָֽיִם", "en": {"kjv": "And utter a parable unto the rebellious house, and say unto them, Thus saith the Lord God; Set on a pot, set it on, and also pour water into it:", "web": "Utter a parable to the rebellious house, and tell them, Thus says the Lord Yahweh, Set on the cauldron, set it on, and also pour water into it:", "bsb": "Now speak a parable to this rebellious house and tell them that this is what the Lord GOD says: ‘Put the pot on the fire; put it on and pour in the water.", "asv": "And utter a parable unto the rebellious house, and say unto them, Thus saith the Lord Jehovah, Set on the caldron, set it on, and also pour water into it:", "ylt": "and use unto the rebellious house a simile, and thou hast said unto them: Thus said the Lord Jehovah: To set on the pot, to set it on, and also to pour into it water,", "dra": "And thou shalt speak by a figure a parable to the provoking house, and say to them: Thus saith the Lord God: Set on a pot, set it on, I say, and put water in it.", "bbe": "And make a comparison for this uncontrolled people, and say to them, This is what the Lord has said: Put on the cooking-pot, put it on the fire and put water in it:", "geneva": "Therefore speake a parable vnto the rebellious house, and say vnto them, Thus sayth the Lord God, Prepare a pot, prepare it, and also powre water into it.", "wycliffe": "And thou schalt seie bi a prouerbe a parable to the hous, terrere to wraththe, and thou schalt speke to hem, The Lord God seith these thingis, Sette thou a brasun pot, sette thou sotheli, and putte thou watir in to it. Take thou a beeste ful fat;", "rotherham": "Put thou forth therefore, against the perverse house a parable, and say unto them Thus saith My Lord, Yahweh: Set on the caldron set it on, Moreover also pour into it water:", "darby": "And propose a parable unto the rebellious house, and say unto them, Thus saith the Lord Jehovah: Set on the pot, set [it] on, and also pour water into it.", "twenty": "", "jps": "And utter a parable concerning the rebellious house, and say unto them: Thus saith the L-rd GOD: Set on the pot, set it on, and also pour water into it;", "acv": "And utter a parable to the rebellious house, and say to them, Thus says the lord Jehovah: Set on the caldron. Set it on, and also pour water into it.", "anderson": "", "haweis": "", "noyes": "Utter a parable to the rebellious house, and say to them, Thus saith the Lord Jehovah: Set on a caldron, set it on, and also pour water into it.", "webster": "And utter a parable to the rebellious house, and say to them, Thus saith the Lord GOD; Set on a pot, set [it] on, and also pour water into it:", "vulgate": "et dices per proverbium ad domum inritatricem parabolam et loqueris ad eos haec dicit Dominus Deus pone ollam pone inquam et mitte in ea aquam;", "brenton": "And speak a parable to the provoking house, and thou shalt say to them, Thus saith the Lord; Set on the caldron, and pour water into it:"}}, {"v": 4, "ref": "24:4", "o": "אֱסֹ֤ף נְתָחֶ֨י/הָ֙ אֵלֶ֔י/הָ כָּל נֵ֥תַח ט֖וֹב יָרֵ֣ךְ וְ/כָתֵ֑ף מִבְחַ֥ר עֲצָמִ֖ים מַלֵּֽא", "en": {"kjv": "Gather the pieces thereof into it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.", "web": "gather its pieces into it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.", "bsb": "Put in the pieces of meat, every good piece— thigh and shoulder— fill it with choice bones.", "asv": "gather the pieces thereof into it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.", "ylt": "To gather its pieces unto it, every good piece, Thigh and shoulder, the choice of the bones to fill in.", "dra": "Heap together into it the pieces thereof, every good piece, the thigh and the shoulder, choice pieces and full of bones.", "bbe": "And get the bits together, the fat tail, every good part, the leg and the top part of it: make it full of the best bones.", "geneva": "Gather the pieces thereof into it, euen euery good piece, as the thigh and the shoulder, and fill it with the chiefe bones.", "wycliffe": "gadere thou togidere the gobetis therof in it, ech good part, and the hipe, and the schuldre, chosun thingis and ful of boonys.", "rotherham": "Gather the pieces thereof into it, Every good piece thigh and shoulder, With the choice of the bones, fill it:", "darby": "Gather the pieces thereof into it, every good piece, the thigh and the shoulder; fill [it] with the choice bones:", "twenty": "", "jps": "Gather into it the pieces belonging to it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.", "acv": "Gather the pieces of it into it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.", "anderson": "", "haweis": "", "noyes": "Gather the pieces thereof into it, even every good piece, the thigh and the shoulder; fill it with the choice bones.", "webster": "Gather its pieces into it, [even] every good piece, the thigh, and the shoulder; fill [it] with the choice bones.", "vulgate": "congere frusta eius in ea omnem partem bonam femur et armum electa et ossibus plena;", "brenton": "and put the pieces into it, every prime piece, the leg and shoulder taken off from the bones,"}}, {"v": 5, "ref": "24:5", "o": "מִבְחַ֤ר הַ/צֹּאן֙ לָק֔וֹחַ וְ/גַ֛ם דּ֥וּר הָ/עֲצָמִ֖ים תַּחְתֶּ֑י/הָ רַתַּ֣ח רְתָחֶ֔י/הָ גַּם בָּשְׁל֥וּ עֲצָמֶ֖י/הָ בְּ/תוֹכָֽ/הּ", "en": {"kjv": "Take the choice of the flock, and burn also the bones under it, and make it boil well, and let them seethe the bones of it therein.", "web": "Take the choice of the flock, and also a pile of wood for the bones under the cauldron; make it boil well; yes, let its bones be boiled in its midst.", "bsb": "Take the choicest of the flock and pile the fuel beneath it. Bring it to a boil and cook the bones in it.’", "asv": "Take the choice of the flock, and also a pile of wood for the bones under the caldron; make it boil well; yea, let the bones thereof be boiled in the midst of it.", "ylt": "The choice of the flock to take, And also to pile of the bones under it, Boil it thoroughly, yea, cook its bones in its midst.", "dra": "Take the fattest of the flock, and lay together piles of bones under it: the seething thereof is boiling hot, and the bones thereof are thoroughly sodden in the midst of it.", "bbe": "Take the best of the flock, put much wood under it: see that its bits are boiling well; let the bones be cooked inside it.", "geneva": "Take one of the best sheepe, and burne also the bones vnder it, and make it boyle well, and seethe the bones of it therein,", "wycliffe": "Also dresse thou heepis of boonys vndur it; and the sething therof buylide out, and the boonys therof weren sodun in the myddis therof.", "rotherham": "Take of the choice of the rock, Moreover also pile of bones place under it,- Boil the pieces thereof, Yea let the bones of it seethe in the midst thereof.", "darby": "take the choice of the flock; and also [put] a pile of wood under it, for the bones; make it boil well, and let the bones of it seethe therein.", "twenty": "", "jps": "Take the choice of the flock, and pile also the bones under it; make it boil well, that the bones thereof may also be seethed in the midst of it.", "acv": "Take the choice of the flock, and also a pile of wood for the bones under the caldron. Make it boil well, yea, let the bones of it be boiled in the midst of it.", "anderson": "", "haweis": "", "noyes": "Take the choice of the flock, and make under it a pile for the bones, and make it boil well, that the bones therein may be seethed.", "webster": "Take the choice of the flock, and burn also the bones under it, [and] make it boil well, and let them boil its bones in it.", "vulgate": "pinguissimum pecus adsume conpone quoque struices ossuum sub ea efferbuit coctio eius et discocta sunt ossa illius in medio eius;", "brenton": "which are taken from choice cattle, and burn the bones under them: her bones are boiled and cooked in the midst of her."}}, {"v": 6, "ref": "24:6", "o": "לָ/כֵ֞ן כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה אוֹי֮ עִ֣יר הַ/דָּמִים֒ סִ֚יר אֲשֶׁ֣ר חֶלְאָתָ֣/ה בָ֔/הּ וְ/חֶ֨לְאָתָ֔/הּ לֹ֥א יָצְאָ֖ה מִמֶּ֑/נָּה לִ/נְתָחֶ֤י/הָ לִ/נְתָחֶ֨י/הָ֙ הוֹצִיאָ֔/הּ לֹא נָפַ֥ל עָלֶ֖י/הָ גּוֹרָֽל", "en": {"kjv": "Wherefore thus saith the Lord God; Woe to the bloody city, to the pot whose scum is therein, and whose scum is not gone out of it! bring it out piece by piece; let no lot fall upon it.", "web": "Therefore thus says the Lord Yahweh: Woe to the bloody city, to the cauldron whose rust is therein, and whose rust is not gone out of it! take out of it piece after piece; No lot is fallen on it.", "bsb": "Therefore this is what the Lord GOD says: ‘Woe to the city of bloodshed, to the pot now rusted, whose rust will not come off! Empty it piece by piece; cast no lots for its contents.", "asv": "Wherefore thus saith the Lord Jehovah: Woe to the bloody city, to the caldron whose rust is therein, and whose rust is not gone out of it! take out of it piece after piece; No lot is fallen upon it.", "ylt": "Therefore, thus said the Lord Jehovah: Woe to the city of blood, A pot whose scum is in it, And its scum hath not come out of it, By piece of it, by piece of it bring it out, Not fallen on it hath a lot.", "dra": "Therefore thus saith the Lord God: Woe to the bloody city, to the pot whose rust is in it, and its rust is not gone out of it: cast it out piece by piece, there hath no lot fallen upon it.", "bbe": "For this is what the Lord has said: A curse is on the town of blood, the cooking-pot which is unclean inside, which has never been made clean! take out its bits; its fate is still to come on it.", "geneva": "Because the Lord God sayth thus, Woe to the bloody citie, euen to the pot, whose skomme is therein, and whose skomme is not gone out of it: bring it out piece by piece: let no lot fall vpon it.", "wycliffe": "Therfor the Lord God seith these thingis, Wo to the citee of bloodis, to the pot whos rust is ther ynne, and the rust therof yede not out of it; caste thou out it bi partis, and bi hise partis; lot felle not on it.", "rotherham": "Wherefore, Thus saith My Lord Yahweh, Woe! city of bloodshed. The caldron whose scum is in it, and whose scum, hath not gone out of it: Piece by piece, bring it out, There hath fallen thereon no lot.", "darby": "Therefore thus saith the Lord Jehovah: Woe to the bloody city, to the pot whose rust is therein, and whose rust is not gone out of it! Bring it out piece by piece; let no lot fall upon it:", "twenty": "", "jps": "Wherefore thus saith the L-rd GOD: Woe to the bloody city, to the pot whose filth is therein, and whose filth is not gone out of it! bring it out piece by piece; no lot is fallen upon it.", "acv": "Therefore thus says the lord Jehovah: Woe to the bloody city, to the caldron whose rust is therein, and whose rust has not gone out of it! Take out of it piece after piece. No lot has fallen upon it.", "anderson": "", "haweis": "", "noyes": "Wherefore thus saith the Lord Jehovah: Woe to the city of blood, to the caldron in which is rust, and whose rust goeth not out of it! bring it out piece by piece; let no lot fall upon it.", "webster": "Wherefore thus saith the Lord GOD; Woe to the bloody city, to the pot whose scum [is] therein, and whose scum is not gone out of it! bring it out piece by piece; let no lot fall upon it.", "vulgate": "propterea haec dicit Dominus Deus vae civitati sanguinum ollae cuius rubigo in ea est et rubigo eius non exivit de ea per partes et per partes suas eice eam non cecidit super eam sors;", "brenton": "Therefore thus saith the Lord; O bloody city, the caldron in which there is scum, and the scum has not gone out of, she has brought it forth piece by piece, no lot has fallen upon it."}}, {"v": 7, "ref": "24:7", "o": "כִּ֤י דָמָ/הּ֙ בְּ/תוֹכָ֣/הּ הָיָ֔ה עַל צְחִ֥יחַ סֶ֖לַע שָׂמָ֑תְ/הוּ לֹ֤א שְׁפָכַ֨תְ/הוּ֙ עַל הָ/אָ֔רֶץ לְ/כַסּ֥וֹת עָלָ֖י/ו עָפָֽר", "en": {"kjv": "For her blood is in the midst of her; she set it upon the top of a rock; she poured it not upon the ground, to cover it with dust;", "web": "For her blood is in the midst of her; she set it on the bare rock; she didn’t pour it on the ground, to cover it with dust.", "bsb": "For the blood she shed is still within her; she poured it out on the bare rock; she did not pour it on the ground to cover it with dust.", "asv": "For her blood is in the midst of her; she set it upon the bare rock; she poured it not upon the ground, to cover it with dust.", "ylt": "For her blood in her midst hath been, On a clear place of a rock she hath set it, She hath not poured it on the earth, To cover it over with dust.", "dra": "For her blood is in the midst of her, she hath shed it upon the smooth rock: she hath not shed it upon the ground, that it might be covered with dust.", "bbe": "For her blood is in her; she has put it on the open rock not draining it on to the earth so that it might be covered with dust;", "geneva": "For her blood is in the middes of her: shee set it vpon an high rocke, and powred it not vpon on the ground to couer it with dust,", "wycliffe": "For whi the blood therof is in the myddis therof; he schede it out on a ful cleer stoon, he schedde not it out on erthe,", "rotherham": "For, her own blood, hath come to be in her midst, Upon the smooth face of the cliff, hath she set it,- She hath not poured it out on the earth, that she might cover it with dust.", "darby": "for her blood is in the midst of her; she set it upon the bare rock; she poured it not upon the ground, to cover it with dust.", "twenty": "", "jps": "For her blood is in the midst of her; she set it upon the bare rock; she poured it not upon the ground, to cover it with dust;", "acv": "For her blood is in the midst of her. She set it upon the bare rock. She did not pour it upon the ground to cover it with dust.", "anderson": "", "haweis": "", "noyes": "For blood is in the midst of her; upon the bare rock hath she shed it; she poured it not upon the ground, that it might be covered with dust.", "webster": "For her blood is in the midst of her; she set it upon the top of a rock; she poured it not upon the ground, to cover it with dust;", "vulgate": "sanguis enim eius in medio eius est super limpidissimam petram effudit illum non effudit illum super terram ut possit operiri pulvere;", "brenton": "For her blood is in the midst of her; I have set it upon a smooth rock: I have not poured it out upon the earth, so that the earth should cover it;"}}, {"v": 8, "ref": "24:8", "o": "לְ/הַעֲל֤וֹת חֵמָה֙ לִ/נְקֹ֣ם נָקָ֔ם נָתַ֥תִּי אֶת דָּמָ֖/הּ עַל צְחִ֣יחַ סָ֑לַע לְ/בִלְתִּ֖י הִכָּסֽוֹת", "en": {"kjv": "That it might cause fury to come up to take vengeance; I have set her blood upon the top of a rock, that it should not be covered.", "web": "That it may cause wrath to come up to take vengeance, I have set her blood on the bare rock, that it should not be covered.", "bsb": "In order to stir up wrath and take vengeance, I have placed her blood on the bare rock, so that it would not be covered.’", "asv": "That it may cause wrath to come up to take vengeance, I have set her blood upon the bare rock, that it should not be covered.", "ylt": "To cause fury to come up to take vengeance, I have put her blood on a clear place of a rock--not to be covered.", "dra": "And that I might bring my indignation upon her, and take my vengeance: I have shed her blood upon the smooth rock, that it should not be covered.", "bbe": "In order that it might make wrath come up to give punishment, she has put her blood on the open rock, so that it may not be covered.", "geneva": "That it might cause wrath to arise, and take vengeance: euen I haue set her blood vpon an high rocke that it should not be couered.", "wycliffe": "that it mai be hilid with dust, that Y schulde bringe in myn indignacioun, and `a venge bi veniaunce; Y yaf the blood therof on a ful cleer stoon, that it schulde not be hilid.", "rotherham": "To bring up indignation to execute an avenging, have I set her blood upon the smooth face of the cliff,—that it may not be covered.", "darby": "That it might cause fury to come up to execute vengeance, I have set her blood upon the bare rock, that it should not be covered.", "twenty": "", "jps": "that it might cause fury to come up, that vengeance might be taken, I have set her blood upon the bare rock, that it should not be covered.", "acv": "That it may cause wrath to come up to take vengeance, I have set her blood upon the bare rock, that it should not be covered.", "anderson": "", "haweis": "", "noyes": "To cause fury and to take vengeance, I have set the blood shed by her upon the bare rock, that it might not be covered.", "webster": "That it might cause fury to come up to take vengeance; I have set her blood upon the top of a rock, that it should not be covered.", "vulgate": "ut superducerem indignationem meam et vindicta ulciscerer dedi sanguinem eius super petram limpidissimam ne operiretur;", "brenton": "that my wrath should come up for complete vengeance to be taken: I set her blood upon a smooth rock, so as not to cover it."}}, {"v": 9, "ref": "24:9", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה א֖וֹי עִ֣יר הַ/דָּמִ֑ים גַּם אֲנִ֖י אַגְדִּ֥יל הַ/מְּדוּרָֽה", "en": {"kjv": "Therefore thus saith the Lord God; Woe to the bloody city! I will even make the pile for fire great.", "web": "Therefore thus says the Lord Yahweh: Woe to the bloody city! I also will make the pile great.", "bsb": "Yes, this is what the Lord GOD says: ‘Woe to the city of bloodshed! I, too, will pile the kindling high.", "asv": "Therefore thus saith the Lord Jehovah: Woe to the bloody city! I also will make the pile great.", "ylt": "Therefore, thus said the Lord Jehovah: Woe to the city of blood, yea, I--I make great the pile.", "dra": "Therefore thus saith the Lord God: Woe to the bloody city, of which I will make a great bonfire.", "bbe": "For this cause the Lord has said: A curse is on the town of blood! and I will make great the burning mass.", "geneva": "Therefore thus saith ye Lord God, Woe to the bloody citie, for I will make ye burning great.", "wycliffe": "Therfor the Lord God seith these thingis, Wo to the citee of bloodis, whos brennyng Y schal make greet;", "rotherham": "Wherefore Thus, saith My Lord Yahweh, Woe! city of bloodshed,—Even I myself, will make large the pile.", "darby": "Therefore thus saith the Lord Jehovah: Woe to the bloody city! I also will make the pile great.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Woe to the bloody city! I also will make the pile great,", "acv": "Therefore thus says the lord Jehovah: Woe to the bloody city! I also will make the pile great.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Woe to the city of blood! Now will I make the pile for fire great.", "webster": "Therefore thus saith the Lord GOD; Woe to the bloody city! I will even make the pile for fire great.", "vulgate": "propterea haec dicit Dominus Deus vae civitati sanguinum cuius ego grandem faciam pyram;", "brenton": "Therefore thus saith the Lord, I will also make the firebrand great,"}}, {"v": 10, "ref": "24:10", "o": "הַרְבֵּ֤ה הָ/עֵצִים֙ הַדְלֵ֣ק הָ/אֵ֔שׁ הָתֵ֖ם הַ/בָּשָׂ֑ר וְ/הַרְקַח֙ הַ/מֶּרְקָחָ֔ה וְ/הָ/עֲצָמ֖וֹת יֵחָֽרוּ", "en": {"kjv": "Heap on wood, kindle the fire, consume the flesh, and spice it well, and let the bones be burned.", "web": "Heap on the wood, make the fire hot, boil well the flesh, and make thick the broth, and let the bones be burned.", "bsb": "Pile on the logs and kindle the fire; cook the meat well and mix in the spices; let the bones be burned.", "asv": "Heap on the wood, make the fire hot, boil well the flesh, and make thick the broth, and let the bones be burned.", "ylt": "Make abundant the wood, Kindle the fire, consume the flesh, And make the compound, And let the bones be burnt.", "dra": "Heap together the bones, which I will burn with fire: the flesh shall be consumed, and the whole composition shall be sodden, and the bones shall be consumed.", "bbe": "Put on much wood, heating up the fire, boiling the flesh well, and making the soup thick, and let the bones be burned.", "geneva": "Heape on much wood: kindle the fire, consume the flesh, and cast in spice, and let the bones be burnt.", "wycliffe": "gadere thou togidire boonys, whiche Y schal kyndle with fier; fleischis schulen be wastid, and al the settyng togidere schal be sodun, and boonys schulen faile.", "rotherham": "Heap on the wood Kindle the fire, Consume the flesh, Yea season with spice, And let the bones be scorched.", "darby": "Heap on the wood, kindle the fire, boil thoroughly the flesh, and spice it well, and let the bones be burned.", "twenty": "", "jps": "heaping on the wood, kindling the fire, that the flesh may be consumed; and preparing the mixture, that the bones also may be burned;", "acv": "Heap on the wood; make the fire hot. Boil the flesh well, and make the broth thick. And let the bones be burned.", "anderson": "", "haweis": "", "noyes": "Heap on wood, kindle the fire, cook the flesh, put in spices, and let the bones be burned.", "webster": "Heap on wood, kindle the fire, consume the flesh, and spice it well, and let the bones be burned.", "vulgate": "congere ossa quae igne succendam consumentur carnes et concoquetur universa conpositio et ossa tabescent;", "brenton": "and I will multiply the wood, and kindle the fire, that the flesh may be consumed, and the liquor boiled away;"}}, {"v": 11, "ref": "24:11", "o": "וְ/הַעֲמִידֶ֥/הָ עַל גֶּחָלֶ֖י/הָ רֵקָ֑ה לְמַ֨עַן תֵּחַ֜ם וְ/חָ֣רָה נְחֻשְׁתָּ֗/הּ וְ/נִתְּכָ֤ה בְ/תוֹכָ/הּ֙ טֻמְאָתָ֔/הּ תִּתֻּ֖ם חֶלְאָתָֽ/הּ", "en": {"kjv": "Then set it empty upon the coals thereof, that the brass of it may be hot, and may burn, and that the filthiness of it may be molten in it, that the scum of it may be consumed.", "web": "Then set it empty on its coals, that it may be hot, and its brass may burn, and that its filthiness may be molten in it, that its rust may be consumed.", "bsb": "Set the empty pot on its coals until it becomes hot and its copper glows. Then its impurity will melt within; its rust will be consumed.", "asv": "Then set it empty upon the coals thereof, that it may be hot, and the brass thereof may burn, and that the filthiness of it may be molten in it, that the rust of it may be consumed.", "ylt": "And cause it to stand on its coals empty, So that its brass is hot and burning, Melted hath been in its midst its uncleanness, Consumed is its scum.", "dra": "Then set it empty upon burning coals, that it may be hot, and the brass thereof may be melted: and let the filth of it be melted in the midst thereof, and let the rust of it be consumed.", "bbe": "And I will put her on the coals so that she may be heated and her brass burned, so that what is unclean in her may become soft and her waste be completely taken away.", "geneva": "Then set it emptie vpon the coles thereof, that the brasse of it may be hot, and may burne, and that the filthinesse of it may be molten in it, and that the skomme of it may be consumed.", "wycliffe": "Also sette thou it voide on coolis, that the metal therof wexe hoot, and be meltid, and that the filthe therof be wellid togidere in the myddis therof, and the rust therof be wastid.", "rotherham": "Then set it upon the live coals thereof empty,—that the copper of it may be scorched and burn. So that the impurity thereof may be annihilated within it The scum thereof be consumed,", "darby": "Then set it empty upon its coals, that it may be hot, and the brass of it may burn, and that its filthiness may be molten in it, [and] that its rust may be consumed.", "twenty": "", "jps": "then will I set it empty upon the coals thereof, that it may be hot, and the bottom thereof may burn, and that the impurity of it may be molten in it, that the filth of it may be consumed", "acv": "Then set it empty upon the coals of it, that it may be hot, and the brass of it may burn, and that the filthiness of it may be molten in it, that the scum of it may be consumed.", "anderson": "", "haweis": "", "noyes": "Then set it empty upon the coals, that its brass may be hot and may burn, and that its impurity may be dissolved in it, and its rust be consumed.", "webster": "Then set it empty upon its coals, that the brass of it may be hot, and may burn, and [that] the filthiness of it may be melted in it, [that] the scum of it may be consumed.", "vulgate": "pone quoque eam super prunas vacuam ut incalescat et liquefiat aes eius et confletur in medio eius inquinamentum eius et consumatur rubigo eius;", "brenton": "and that it may stand upon the coals, that her brass may be thoroughly heated, and be melted in the midst of her filthiness, and her scum may be consumed,"}}, {"v": 12, "ref": "24:12", "o": "תְּאֻנִ֖ים הֶלְאָ֑ת וְ/לֹֽא תֵצֵ֤א מִמֶּ֨/נָּה֙ רַבַּ֣ת חֶלְאָתָ֔/הּ בְּ/אֵ֖שׁ חֶלְאָתָֽ/הּ", "en": {"kjv": "She hath wearied herself with lies, and her great scum went not forth out of her: her scum shall be in the fire.", "web": "She is weary with toil; yet her great rust doesn’t go leave her; her rust doesn’t go by fire.", "bsb": "It has frustrated every effort; its thick rust has not been removed, even by the fire.", "asv": "She hath wearied herself with toil; yet her great rust goeth not forth out of her; her rust goeth not forth by fire.", "ylt": "With sorrows she hath wearied herself, And the abundance of her scum goeth not out of her, In the fire is her scum.", "dra": "Great pains have been taken, and the great rust thereof is not gone out, not even by fire.", "bbe": "I have made myself tired to no purpose: still all the waste which is in her has not come out, it has an evil smell.", "geneva": "She hath wearied her selfe with lyes, and her great skomme went not out of her: therefore her skomme shall be consumed with fire.", "wycliffe": "It was swat bi myche trauel, and the ouer greet rust therof yede not out therof, nether bi fier.", "rotherham": "With toils, hath she wearied herself,—Since her abundant scum will not go out of her, into the fire, with her scum!", "darby": "She hath exhausted [her] labours, yet her great rust goeth not forth out of her: let her rust be in the fire.", "twenty": "", "jps": "It hath wearied itself with toil; yet its great filth goeth not forth out of it, yea, its noisome filth.", "acv": "She has wearied herself with toil, yet her great scum does not go forth out of her, her scum by fire.", "anderson": "", "haweis": "", "noyes": "It hath wearied me with labors, yet its thick rust goeth not from it; its rust remaineth in the midst of the fire.", "webster": "She hath wearied [herself] with lies, and her great scum went not forth out of her: her scum [shall be] in the fire.", "vulgate": "multo labore sudatum est et non exibit de ea nimia rubigo eius neque per ignem;", "brenton": "and her abundant scum may not come forth of her."}}, {"v": 13, "ref": "24:13", "o": "בְּ/טֻמְאָתֵ֖/ךְ זִמָּ֑ה יַ֤עַן טִֽהַרְתִּי/ךְ֙ וְ/לֹ֣א טָהַ֔רְתְּ מִ/טֻּמְאָתֵ/ךְ֙ לֹ֣א תִטְהֲרִי ע֔וֹד עַד הֲנִיחִ֥/י אֶת חֲמָתִ֖/י בָּֽ/ךְ", "en": {"kjv": "In thy filthiness is lewdness: because I have purged thee, and thou wast not purged, thou shalt not be purged from thy filthiness any more, till I have caused my fury to rest upon thee.", "web": "In your filthiness is lewdness: because I have cleansed you and you weren’t cleansed, you shall not be cleansed from your filthiness any more, until I have caused my wrath toward you to rest.", "bsb": "Because of the indecency of your uncleanness I tried to cleanse you, but you would not be purified from your filthiness. You will not be pure again until My wrath against you has subsided.", "asv": "In thy filthiness is lewdness: because I have cleansed thee and thou wast not cleansed, thou shalt not be cleansed from thy filthiness any more, till I have caused my wrath toward thee to rest.", "ylt": "In thine uncleanness is wickedness, Because I have cleansed thee, And thou hast not been cleansed, From thine uncleanness thou art not cleansed again, Till I have caused My fury to rest on thee.", "dra": "Thy uncleanness is execrable: because I desired to cleanse thee, and thou art not cleansed from thy filthiness: neither shalt thou be cleansed, before I cause my indignation to rest in thee.", "bbe": "As for your unclean purpose: because I have been attempting to make you clean, but you have not been made clean from it, you will not be made clean till I have let loose my passion on you in full measure.", "geneva": "Thou remainest in thy filthines and wickednes: because I would haue purged thee, and thou wast not purged, thou shalt not be purged from thy filthines, till I haue caused my wrath to light vpon thee.", "wycliffe": "Thin vnclennesse is abhomynable, for Y wolde clense thee, and thou art not clensid fro thi filthis; but nether thou schalt be clensid bifore, til Y make myn indignacioun to reste in thee.", "rotherham": "In thine uncleanness, is lewdness; be- cause I purified thee and thou wast not purified, from thine uncleanness, thou shalt not be purified any more, until I have let mine indignation rest upon thee.", "darby": "In thy filthiness is lewdness, for I have purged thee, and thou art not pure. Thou shalt no more be purged from thy filthiness, till I have satisfied my fury upon thee.", "twenty": "", "jps": "Because of thy filthy lewdness, because I have purged thee and thou wast not purged, thou shalt not be purged from thy filthiness any more, till I have satisfied My fury upon thee.", "acv": "In thy filthiness is lewdness. Because I have cleansed thee and thou were not cleansed, thou shall not be cleansed from thy filthiness any more, till I have caused my wrath toward thee to rest.", "anderson": "", "haweis": "", "noyes": "In thy filthiness is gross wickedness, because, when I would have cleansed thee, thou wouldst not be cleansed. Thou shalt not be cleansed from thy filthiness any more, till I have quieted my fury toward thee.", "webster": "In thy filthiness [is] lewdness: because I have purged thee, and thou wast not purged, thou shalt not be purged from thy filthiness any more, till I have caused my fury to rest upon thee.", "vulgate": "inmunditia tua execrabilis quia mundare te volui et non es mundata a sordibus tuis sed nec mundaberis prius donec quiescere faciam indignationem meam in te;", "brenton": "Her scum shall become shameful, because thou didst defile thyself: and what if thou shalt be purged no more until I have accomplished my wrath?"}}, {"v": 14, "ref": "24:14", "o": "אֲנִ֨י יְהוָ֤ה דִּבַּ֨רְתִּי֙ בָּאָ֣ה וְ/עָשִׂ֔יתִי לֹֽא אֶפְרַ֥ע וְ/לֹא אָח֖וּס וְ/לֹ֣א אֶנָּחֵ֑ם כִּ/דְרָכַ֤יִ/ךְ וְ/כַ/עֲלִילוֹתַ֨יִ/ךְ֙ שְׁפָט֔וּ/ךְ נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "I the Lord have spoken it: it shall come to pass, and I will do it; I will not go back, neither will I spare, neither will I repent; according to thy ways, and according to thy doings, shall they judge thee, saith the Lord God.", "web": "I, Yahweh, have spoken it: it shall happen, and I will do it: I will not go back, neither will I spare, neither will I repent; according to your ways, and according to your doings, shall they judge you, says the Lord Yahweh.", "bsb": "I, the LORD, have spoken; the time is coming, and I will act. I will not refrain or show pity, nor will I relent. I will judge you according to your ways and deeds,’ declares the Lord GOD.”", "asv": "I, Jehovah, have spoken it: it shall come to pass, and I will do it: I will not go back, neither will I spare, neither will I repent; according to thy ways, and according to thy doings, shall they judge thee, saith the Lord Jehovah.", "ylt": "I, Jehovah, hath spoken, It hath come, and I have done it , I do not free, nor do I spare, nor do I repent, According to thy ways, and according to thine acts, they have judged thee, An affirmation of the Lord Jehovah.'", "dra": "I the Lord have spoken: it shall come to pass, and I will do it: I will not pass by, nor spare, nor be pacified: I will judge thee according to thy ways, and according to thy doings, saith the Lord.", "bbe": "I the Lord have said the word and I will do it; I will not go back or have mercy, and my purpose will not be changed; in the measure of your ways and of your evil doings you will be judged, says the Lord.", "geneva": "I the Lord haue spoken it: it shall come to passe, and I will doe it: I will not goe backe, neither will I spare, neither will I repent: according to thy wayes, and according to thy workes shall they iudge thee, sayeth the Lord God.", "wycliffe": "Y the Lord spak; it schal come, and Y schal make, Y schal not passe, nethir Y schal spare, nether Y schal be plesid; bi thi weies and bi thi fyndyngis Y schal deme thee, seith the Lord.", "rotherham": "I Yahweh, have spoken It cometh and I will perform I will not let alone, neither will I shield, Nor will I repent,- According to thy ways and according to thy doings, have they judged thee, Declareth My Lord Yahweh.", "darby": "I Jehovah have spoken [it]: it shall come to pass, and I will do it; I will not go back, neither will I spare, nor will I repent. According to thy ways, and according to thy doings, shall they judge thee, saith the Lord Jehovah.", "twenty": "", "jps": "I HaShem have spoken it; it shall come to pass, and I will do it; I will not go back, neither will I spare, neither will I repent; according to thy ways, and according to thy doings, shall they judge thee, saith the L-rd GOD.'", "acv": "I, Jehovah, have spoken it. It shall come to pass, and I will do it. I will not go back. I will neither spare, nor will I relent. According to thy ways, and according to thy doings, they shall judge thee, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "I, Jehovah, have spoken it; it shall come to pass, and I will do it. I will not go back, neither will I spare, neither will I repent. According to thy ways and according to thy doings shall they judge thee, saith the Lord Jehovah.", "webster": "I the LORD have spoken [it]; it shall come to pass, and I will do [it]; I will not go back, neither will I spare, neither will I repent; according to thy ways, and according to thy doings, shall they judge thee, saith the Lord GOD.", "vulgate": "ego Dominus locutus sum venit et faciam non transeam nec parcam nec placabor iuxta vias tuas et iuxta adinventiones tuas iudicavi te dicit Dominus;", "brenton": "I the Lord have spoken; and it shall come, and I will do it; I will not delay, neither will I have any mercy: I will judge thee, saith the Lord, according to thy ways, and according to thy devices: therefore will I judge thee according to thy bloodshed, and according to thy devices will I judge thee, thou unclean, notorious, and abundantly provoking one."}}, {"v": 15, "ref": "24:15", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Also the word of the Lord came unto me, saying,", "web": "Also Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "Also the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Also the worde of ye Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Also the word of HaShem came unto me, saying:", "acv": "Also the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Also the word of Jehovah came to me, saying:", "webster": "Also the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 16, "ref": "24:16", "o": "בֶּן אָדָ֕ם הִנְ/נִ֨י לֹקֵ֧חַ מִמְּ/ךָ֛ אֶת מַחְמַ֥ד עֵינֶ֖י/ךָ בְּ/מַגֵּפָ֑ה וְ/לֹ֤א תִסְפֹּד֙ וְ/לֹ֣א תִבְכֶּ֔ה וְ/ל֥וֹא תָב֖וֹא דִּמְעָתֶֽ/ךָ", "en": {"kjv": "Son of man, behold, I take away from thee the desire of thine eyes with a stroke: yet neither shalt thou mourn nor weep, neither shall thy tears run down.", "web": "Son of man, behold, I will take away from you the desire of your eyes with a stroke: yet you shall neither mourn nor weep, neither shall your tears run down.", "bsb": "“Son of man, behold, I am about to take away the desire of your eyes with a fatal blow. But you must not mourn or weep or let your tears flow.", "asv": "Son of man, behold, I take away from thee the desire of thine eyes with a stroke: yet thou shalt neither mourn nor weep, neither shall thy tears run down.", "ylt": "`Son of man, lo, I am taking from thee the desire of thine eyes by a stroke, and thou dost not mourn, nor weep, nor let thy tear come.", "dra": "Son of man, behold I take from thee the desire of thy eyes with a stroke, and thou shall not lament, nor weep; neither shall thy tears run down.", "bbe": "Son of man, see, I am taking away the desire of your eyes by disease: but let there be no sorrow or weeping or drops running from your eyes.", "geneva": "Sonne of man beholde, I take away from thee the pleasure of thine eyes with a plague: yet shalt thou neither mourne nor weepe, neither shall thy teares runne downe.", "wycliffe": "and he seide, Thou, sone of man, lo! Y take awei fro thee the desirable thing of thin iyen in veniaunce, and thou schalt not weile, nether wepe, nether thi teeris schulen flete doun.", "rotherham": "Son of Man Behold me! taking away from thee the delight of thine eyes, with a stroke,- But thou shall not lament Neither shalt thou weep, Neither shall come—thy tears:", "darby": "Son of man, behold, I take away from thee the desire of thine eyes with a stroke; yet thou shalt not mourn nor weep, neither shall thy tears run down.", "twenty": "", "jps": "'Son of man, behold, I take away from thee the desire of thine eyes with a stroke; yet neither shalt thou make lamentation nor weep, neither shall thy tears run down.", "acv": "Son of man, behold, I take the desire of thine eyes away from thee with a stroke. Yet thou shall neither mourn nor weep. Neither shall thy tears run down.", "anderson": "", "haweis": "", "noyes": "Son of man, behold, I take away from thee the desire of thine eyes with one blow; yet thou shalt not mourn, nor weep, nor shall thy tears run down.", "webster": "Son of man, behold, I take away from thee the desire of thy eyes with a stroke: yet neither shalt thou mourn nor weep, neither shall thy tears run down.", "vulgate": "fili hominis ecce ego tollo a te desiderabile oculorum tuorum in plaga et non planges neque plorabis neque fluent lacrimae tuae;", "brenton": "Son of man, behold I take from thee the desire of thine eyes by violence: thou shalt not lament, neither shalt thou weep."}}, {"v": 17, "ref": "24:17", "o": "הֵאָנֵ֣ק דֹּ֗ם מֵתִים֙ אֵ֣בֶל לֹֽא תַֽעֲשֶׂ֔ה פְאֵֽרְ/ךָ֙ חֲב֣וֹשׁ עָלֶ֔י/ךָ וּ/נְעָלֶ֖י/ךָ תָּשִׂ֣ים בְּ/רַגְלֶ֑י/ךָ וְ/לֹ֤א תַעְטֶה֙ עַל שָׂפָ֔ם וְ/לֶ֥חֶם אֲנָשִׁ֖ים לֹ֥א תֹאכֵֽל", "en": {"kjv": "Forbear to cry, make no mourning for the dead, bind the tire of thine head upon thee, and put on thy shoes upon thy feet, and cover not thy lips, and eat not the bread of men.", "web": "Sigh, but not aloud, make no mourning for the dead; bind your headdress on you, and put your shoes on your feet, and don’t cover your lips, and don’t eat men’s bread.", "bsb": "Groan quietly; do not mourn for the dead. Put on your turban and strap your sandals on your feet; do not cover your lips or eat the bread of mourners.”", "asv": "Sigh, but not aloud, make no mourning for the dead; bind thy headtire upon thee, and put thy shoes upon thy feet, and cover not thy lips, and eat not the bread of men.", "ylt": "Cease to groan, for the dead thou dost make no mourning, thy bonnet bind on thee, and thy shoes thou dost put on thy feet, and thou dost not cover over the upper lip, and bread of men thou dost not eat.'", "dra": "Sigh in silence, make no mourning for the dead: let the tire of thy head be upon thee, and thy shoes on thy feet, and cover not thy face, nor eat the meat of mourners.", "bbe": "Let there be no sound of sorrow; make no weeping for your dead, put on your head-dress and your shoes on your feet, let not your lips be covered, and do not take the food of those in grief.", "geneva": "Cease from sighing: make no mourning for the dead, and binde the tyre of thine head vpon thee, and put on thy shooes vpon thy feete, and couer not thy lips, and eate not the bread of men.", "wycliffe": "Weile thou beynge stille, thou schalt not make mourenyng of deed men; thi coroun be boundun aboute thin heed, and thi schoon schulen be in the feet, nether thou schalt hile the mouth with a cloth, nether thou schalt ete the metis of mourneris.", "rotherham": "To groan, forbear, Over the dead—no mourning, shalt thou make Thy chaplet, bind thou on thee And thy sandals:, put thou on thy feet, And thou shalt not cover thy beard, And the bread of other men, shalt thou not eat.", "darby": "Sigh in silence, make no mourning for the dead; bind thy turban upon thee, and put thy sandals upon thy feet, and cover not the beard, and eat not the bread of men.", "twenty": "", "jps": "Sigh in silence; make no mourning for the dead, bind thy headtire upon thee, and put thy shoes upon thy feet, and cover not thine upper lip, and eat not the bread of men.'", "acv": "Sigh, but not aloud. Make no mourning for the dead. Bind thy headdress upon thee, and put thy shoes upon thy feet. And do not cover thy lips, and do not eat the bread of men.", "anderson": "", "haweis": "", "noyes": "Sigh thou in silence, make no mourning for the dead; bind thy head-dress upon thee, and thy shoes on thy feet; cover not thy lips, and eat not the bread of wretched men.", "webster": "Forbear to cry, make no mourning for the dead, bind the tire of thy head upon thee, and put on thy shoes upon thy feet, and cover not [thy] lips, and eat not the bread of men.", "vulgate": "ingemesce tacens mortuorum luctum non facies corona tua circumligata sit tibi et calciamenta tua erunt in pedibus tuis nec amictu ora velabis nec cibos lugentium comedes;", "brenton": "Thou shalt groan for blood, and have mourning upon thy loins; thy hair shall not be braided upon thee, and thy sandals shall be on thy feet; thou shalt in no wise be comforted by their lips, and thou shalt not eat the bread of men."}}, {"v": 18, "ref": "24:18", "o": "וָ/אֲדַבֵּ֤ר אֶל הָ/עָם֙ בַּ/בֹּ֔קֶר וַ/תָּ֥מָת אִשְׁתִּ֖/י בָּ/עָ֑רֶב וָ/אַ֥עַשׂ בַּ/בֹּ֖קֶר כַּ/אֲשֶׁ֥ר צֻוֵּֽיתִי", "en": {"kjv": "So I spake unto the people in the morning: and at even my wife died; and I did in the morning as I was commanded.", "web": "So I spoke to the people in the morning; and at even my wife died; and I did in the morning as I was commanded.", "bsb": "So I spoke to the people in the morning, and in the evening my wife died. And the next morning I did as I had been commanded.", "asv": "So I spake unto the people in the morning; and at even my wife died; and I did in the morning as I was commanded.", "ylt": "And I speak unto the people in the morning, and my wife dieth in the evening, and I do in the morning as I have been commanded.", "dra": "So I spoke to the people in the morning, and my wife died in the evening: and I did in the morning as he had commanded me.", "bbe": "So in the morning I was teaching the people and in the evening death took my wife; and in the morning I did what I had been ordered to do.", "geneva": "So I spake vnto the people in the morning, and at euen my wife dyed: and I did in the morning, as I was commanded.", "wycliffe": "Therfor Y spak to the puple in the morewtid, and my wijf was deed in the euentid; and Y dide in the morewtid, as he hadde comaundid to me.", "rotherham": "So I spake unto the people in the morning, and my wife died in the evening,—and I did in the morning, as I had been commanded.", "darby": "— And I spoke unto the people in the morning; and at even my wife died. And I did in the morning as I was commanded.", "twenty": "", "jps": "So I spoke unto the people in the morning, and at even my wife died; and I did in the morning as I was commanded.", "acv": "So I spoke to the people in the morning, and at evening my wife died. And I did in the morning as I was commanded.", "anderson": "", "haweis": "", "noyes": "So I spake to the people in the morning, and my wife died in the evening; and I did in the morning as I was commanded.", "webster": "So I spoke to the people in the morning: and at evening my wife died; and I did in the morning as I was commanded.", "vulgate": "locutus sum ergo ad populum mane et mortua est uxor mea vesperi fecique mane sicut praeceperat mihi;", "brenton": "And I spoke to the people in the morning, as he commanded me in the evening, and I did in the morning as it was commanded me."}}, {"v": 19, "ref": "24:19", "o": "וַ/יֹּאמְר֥וּ אֵלַ֖/י הָ/עָ֑ם הֲ/לֹֽא תַגִּ֥יד לָ֨/נוּ֙ מָה אֵ֣לֶּה לָּ֔/נוּ כִּ֥י אַתָּ֖ה עֹשֶֽׂה", "en": {"kjv": "And the people said unto me, Wilt thou not tell us what these things are to us, that thou doest so?", "web": "The people said to me, Won’t you tell us what these things are to us, that you do so?", "bsb": "Then the people asked me, “Won’t you tell us what these things you are doing mean to us?”", "asv": "And the people said unto me, Wilt thou not tell us what these things are to us, that thou doest so?", "ylt": "And the people say unto me, `Dost thou not declare to us what these are to us, that thou art doing?'", "dra": "And the people said to me: Why dost thou not tell us what these things mean that thou doest?", "bbe": "And the people said to me, Will you not make clear to us the sense of these things; is it for us you do them?", "geneva": "And the people said vnto me, Wilt thou not tell vs what these things meane towarde vs that thou doest so?", "wycliffe": "And the puple seide to me, Whi schewist thou not to vs what these thingis signefien, whiche thou doist?", "rotherham": "Then said the people unto me: Wilt thou not tell us what these things are to us, that thou shouldst be acting thus?", "darby": "And the people said unto me, Wilt thou not tell us what these things are to us, which thou doest?", "twenty": "", "jps": "And the people said unto me: 'Wilt thou not tell us what these things are to us, that thou doest so?'", "acv": "And the people said to me, Will thou not tell us what these things are to us, that thou do so?", "anderson": "", "haweis": "", "noyes": "And the people said to me, Wilt thou not tell us what those things which thou doest denote to us?", "webster": "And the people said to me, Wilt thou not tell us what these [things are] to us, that thou doest [so]?", "vulgate": "et dixit ad me populus quare non indicas nobis quid ista significent quae tu facis;", "brenton": "And the people said to me, Wilt thou not tell us what these things are that thou doest?"}}, {"v": 20, "ref": "24:20", "o": "וָ/אֹמַ֖ר אֲלֵי/הֶ֑ם דְּבַ֨ר יְהוָ֔ה הָיָ֥ה אֵלַ֖/י לֵ/אמֹֽר", "en": {"kjv": "Then I answered them, The word of the Lord came unto me, saying,", "web": "Then I said to them, Yahweh’s word came to me, saying,", "bsb": "So I answered them, “The word of the LORD came to me, saying:", "asv": "Then I said unto them, The word of Jehovah came unto me, saying,", "ylt": "And I say unto them, `A word of Jehovah hath been unto me, saying:", "dra": "And I said to them: The word of the Lord came to me, saying:", "bbe": "Then I said to them, The word of the Lord came to me, saying,", "geneva": "Then I answered them, The worde of the Lord came vnto me, saying,", "wycliffe": "And Y seide to hem, The word of the Lord was maad to me,", "rotherham": "So I said unto them: The word of Yahweh hath come unto me, saying:", "darby": "And I said to them, The word of Jehovah came unto me, saying,", "twenty": "", "jps": "Then I said unto them: 'The word of HaShem came unto me, saying:", "acv": "Then I said to them, The word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Then I answered them: The word of Jehovah came to me and said:", "webster": "Then I answered them, the word of the LORD came to me, saying,", "vulgate": "et dixi ad eos sermo Domini factus est ad me dicens;", "brenton": "Then I said to them, The word of the Lord came to me, saying,"}}, {"v": 21, "ref": "24:21", "o": "אֱמֹ֣ר לְ/בֵ֣ית יִשְׂרָאֵ֗ל כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִנְ/נִ֨י מְחַלֵּ֤ל אֶת מִקְדָּשִׁ/י֙ גְּא֣וֹן עֻזְּ/כֶ֔ם מַחְמַ֥ד עֵֽינֵי/כֶ֖ם וּ/מַחְמַ֣ל נַפְשְׁ/כֶ֑ם וּ/בְנֵי/כֶ֧ם וּ/בְנֽוֹתֵי/כֶ֛ם אֲשֶׁ֥ר עֲזַבְתֶּ֖ם בַּ/חֶ֥רֶב יִפֹּֽלוּ", "en": {"kjv": "Speak unto the house of Israel, Thus saith the Lord God; Behold, I will profane my sanctuary, the excellency of your strength, the desire of your eyes, and that which your soul pitieth; and your sons and your daughters whom ye have left shall fall by the sword.", "web": "Speak to the house of Israel, Thus says the Lord Yahweh: Behold, I will profane my sanctuary, the pride of your power, the desire of your eyes, and that which your soul pities; and your sons and your daughters whom you have left behind shall fall by the sword.", "bsb": "Tell the house of Israel that this is what the Lord GOD says: ‘I am about to desecrate My sanctuary, the pride of your power, the desire of your eyes, and the delight of your soul. And the sons and daughters you left behind will fall by the sword.’", "asv": "Speak unto the house of Israel, Thus saith the Lord Jehovah: Behold, I will profane my sanctuary, the pride of your power, the desire of your eyes, and that which your soul pitieth; and your sons and your daughters whom ye have left behind shall fall by the sword.", "ylt": "Say to the house of Israel: Thus said the Lord Jehovah: Lo, I am polluting My sanctuary, The excellency of your strength, The desire of your eyes, and the pitied of your soul, And your sons and your daughters whom ye have left, by sword they do fall.", "dra": "Speak to the house of Israel: Thus saith the Lord God: Behold I will profane my sanctuary, the glory of your realm, and the thing that your eyes desire, and for which your soul feareth: your sons, and your daughters, whom you have left, shall fall by the sword.", "bbe": "Say to the people of Israel, The Lord has said, See, I will make my holy place unclean, the pride of your strength, the pleasure of your eyes, and the desire of your soul; and your sons and daughters, who did not come with you here, will be put to the sword.", "geneva": "Speake vnto the house of Israel, Thus sayth the Lord God, Behold, I will pollute my Sanctuarie, euen the pride of your power, the pleasure of your eyes, and your hearts desire, and your sonnes, and your daughters whom ye haue left, shall fall by the sworde.", "wycliffe": "and he seide, Speke thou to the hous of Israel, The Lord God seith these thingis, Lo! Y schal defoule my seyntuarie, the pride of youre empire, and the desirable thing of youre iyen, and on which youre soule dredith; and youre sones and youre douytris, whiche ye leften, schulen falle bi swerd.", "rotherham": "Say to the house of Israel thus, saith My Lord. Yahweh, Behold me! profaning my sanctuary. The pride of your strength, The delight of your eyes And the object of the tender regard of your soul,- And your sons and your daughters whom ye have left behind, by the sword, shall fall.", "darby": "Say unto the house of Israel, Thus saith the Lord Jehovah: Behold, I will profane my sanctuary, the pride of your strength, the desire of your eyes, and your soul's longing; and your sons and your daughters whom ye have left behind shall fall by the sword.", "twenty": "", "jps": "Speak unto the house of Israel: Thus saith the L-rd GOD: Behold, I will profane My sanctuary, the pride of your power, the desire of your eyes, and the longing of your soul; and your sons and your daughters whom ye have left behind shall fall by the sword.", "acv": "Speak to the house of Israel, Thus says the lord Jehovah: Behold, I will profane my sanctuary, the pride of your power, the desire of your eyes, and that which your soul has compassion. And your sons and your daughters whom ye have left behind shall fall by the sword.", "anderson": "", "haweis": "", "noyes": "Say to the house of Israel, Thus saith the Lord Jehovah: Behold, I will profane my sanctuary, the pride of your confidence, the desire of your eyes, and the longing of your souls; and your sons and daughters that are left to you shall fall by the sword.", "webster": "Speak to the house of Israel, Thus saith the Lord GOD; Behold, I will profane my sanctuary, the excellence of your strength, the desire of your eyes, and that which your soul pitieth; and your sons and your daughters whom ye have left shall fall by the sword.", "vulgate": "loquere domui Israhel haec dicit Dominus Deus ecce ego polluam sanctuarium meum superbiam imperii vestri et desiderabile oculorum vestrorum et super quo pavet anima vestra et filii vestri et filiae quas reliquistis gladio cadent;", "brenton": "Say to the house of Israel, Thus saith the Lord; Behold, I will profane my sanctuary, the boast of your strength, the desire of your eyes, and for which your souls are concerned; and your sons and your daughters, whom ye have left, shall fall by the sword."}}, {"v": 22, "ref": "24:22", "o": "וַ/עֲשִׂיתֶ֖ם כַּ/אֲשֶׁ֣ר עָשִׂ֑יתִי עַל שָׂפָם֙ לֹ֣א תַעְט֔וּ וְ/לֶ֥חֶם אֲנָשִׁ֖ים לֹ֥א תֹאכֵֽלוּ", "en": {"kjv": "And ye shall do as I have done: ye shall not cover your lips, nor eat the bread of men.", "web": "You shall do as I have done: you shall not cover your lips, nor eat the bread of men.", "bsb": "Then you will do as I have done: You will not cover your lips or eat the bread of mourners.", "asv": "And ye shall do as I have done: ye shall not cover your lips, nor eat the bread of men.", "ylt": "And ye have done as I have done, On the upper lip ye are not covered, And bread of men ye do not eat.", "dra": "And you shall do as I have done: you shall not cover your faces, nor shall you eat the meat of mourners.", "bbe": "And you will do as I have done, not covering your lips or taking the food of those in grief.", "geneva": "And ye shall doe as I haue done: ye shall not couer your lippes, neither shall ye eate the bread of men.", "wycliffe": "And ye schulen do, as Y dide; ye schulen not hile mouthis with cloth, and ye schulen not ete the mete of weileris.", "rotherham": "Then shall ye do, as I have done.— The beard, shall ye not cover, And the bread of other men:, shall ye not eat;", "darby": "And ye shall do as I have done: ye shall not cover the beard, neither eat the bread of men;", "twenty": "", "jps": "And ye shall do as I have done: ye shall not cover your upper lips, nor eat the bread of men;", "acv": "And ye shall do as I have done. Ye shall not cover your lips, nor eat the bread of men.", "anderson": "", "haweis": "", "noyes": "And ye shall do as I have done; ye shall not cover your mouths, nor eat the bread of wretched men;", "webster": "And ye shall do as I have done: ye shall not cover [your] lips, nor eat the bread of men.", "vulgate": "et facietis sicut feci ora amictu non velabitis et cibos lugentium non comedetis;", "brenton": "And ye shall do as I have done: ye shall not be comforted at their mouth, and ye shall not eat the bread of men."}}, {"v": 23, "ref": "24:23", "o": "וּ/פְאֵרֵ/כֶ֣ם עַל רָאשֵׁי/כֶ֗ם וְ/נַֽעֲלֵי/כֶם֙ בְּ/רַגְלֵי/כֶ֔ם לֹ֥א תִסְפְּד֖וּ וְ/לֹ֣א תִבְכּ֑וּ וּ/נְמַקֹּתֶם֙ בַּ/עֲוֺנֹ֣תֵי/כֶ֔ם וּ/נְהַמְתֶּ֖ם אִ֥ישׁ אֶל אָחִֽי/ו", "en": {"kjv": "And your tires shall be upon your heads, and your shoes upon your feet: ye shall not mourn nor weep; but ye shall pine away for your iniquities, and mourn one toward another.", "web": "Your tires shall be on your heads, and your shoes on your feet: you shall not mourn nor weep; but you shall pine away in your iniquities, and moan one toward another.", "bsb": "Your turbans will remain on your heads and your sandals on your feet. You will not mourn or weep, but you will waste away because of your sins, and you will groan among yourselves.", "asv": "And your tires shall be upon your heads, and your shoes upon your feet: ye shall not mourn nor weep; but ye shall pine away in your iniquities, and moan one toward another.", "ylt": "And your bonnets are on your heads, And your shoes are on your feet, Ye do not mourn nor do ye weep, And ye have wasted away for your iniquities, And ye have howled one unto another.", "dra": "You shall have crowns on your heads, and shoes on your feet: you shall not lament nor weep, but you shall pine away for your iniquities, and every one shall sigh with his brother.", "bbe": "And your head-dresses will be on your heads and your shoes on your feet: there will be no sorrow or weeping; but you will be wasting away in the punishment of your evil-doing, and you will be looking at one another in wonder.", "geneva": "And your tyre shalbe vpon your heads, and your shooes vpon your feete: ye shall not mourne nor weepe, but ye shall pine away for your iniquities, and mourne one toward another.", "wycliffe": "Ye schulen haue corouns in youre heedis, and schoon in the feet; ye schulen not weile, nether ye schulen wepe, but ye schulen faile in wretchidnesse, for youre wickidnessis; and ech man schal weile to his brother.", "rotherham": "And your chaplets shall be on your heads. And your sandals on your feet, Ye shall neither lament, nor weep,- Yet shall ye pine away in your iniquities, and shall groan one to another.", "darby": "and your turbans shall be upon your heads, and your sandals upon your feet: ye shall not mourn nor weep; but ye shall waste away in your iniquities and moan one toward another.", "twenty": "", "jps": "and your tires shall be upon your heads, and your shoes upon your feet; ye shall not make lamentation nor weep; but ye shall pine away in your iniquities, and moan one toward another.", "acv": "And your coverings shall be upon your heads, and your shoes upon your feet. Ye shall not mourn nor weep, but ye shall pine away in your iniquities, and moan one toward another.", "anderson": "", "haweis": "", "noyes": "and your head-dresses shall be upon your heads, and your shoes upon your feet; ye shall not mourn nor weep; but ye shall pine away for your iniquities, and moan one to another.", "webster": "And your tires [shall be] upon your heads, and your shoes upon your feet: ye shall not mourn nor weep; but ye shall pine away for your iniquities, and mourn one towards another.", "vulgate": "coronas habebitis in capitibus vestris et calciamenta in pedibus non plangetis neque flebitis sed tabescetis in iniquitatibus vestris et unusquisque gemet ad fratrem suum;", "brenton": "And your hair shall be upon your head, and your shoes on your feet: neither shall ye at all lament or weep; but ye shall pine away in your iniquities, and shall comfort every one his brother."}}, {"v": 24, "ref": "24:24", "o": "וְ/הָיָ֨ה יְחֶזְקֵ֤אל לָ/כֶם֙ לְ/מוֹפֵ֔ת כְּ/כֹ֥ל אֲשֶׁר עָשָׂ֖ה תַּעֲשׂ֑וּ בְּ/בֹאָ֕/הּ וִֽ/ידַעְתֶּ֕ם כִּ֥י אֲנִ֖י אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thus Ezekiel is unto you a sign: according to all that he hath done shall ye do: and when this cometh, ye shall know that I am the Lord God.", "web": "Thus Ezekiel shall be a sign to you; according to all that he has done, you will do. When this comes, then you will know that I am the Lord Yahweh.", "bsb": "‘Thus Ezekiel will be a sign for you; you will do everything that he has done. When this happens, you will know that I am the Lord GOD.’", "asv": "Thus shall Ezekiel be unto you a sign; according to all that he hath done shall ye do: when this cometh, then shall ye know that I am the Lord Jehovah.", "ylt": "And Ezekiel hath been to you for a type, According to all that he hath done ye do; In its coming in--ye have known that I am the Lord Jehovah.", "dra": "And Ezekiel shall be unto you for a sign of things to come: according to all that he hath done, so shall you do, when this shall come to pass: and you shall know that I am the Lord God.", "bbe": "And Ezekiel will be a sign to you; everything he has done you will do: when this takes place, you will be certain that I am the Lord.", "geneva": "Thus Ezekiel is vnto you a signe: according to all that he hath done, ye shall do: and when this commeth, ye shall know that I am the Lord God.", "wycliffe": "And Ezechiel schal be to you in to a signe of thing to comynge; bi alle thingis whiche he dide, ye schulen do, whanne this thing schal come; and ye schulen wite, that Y am the Lord God.", "rotherham": "So shall Ezekiel become to you a wonder, According to all that he hath done, shall ye do: When it cometh, then shall ye know that I am The Lord, Yahweh.", "darby": "Thus Ezekiel shall be unto you a sign; according to all that he hath done shall ye do: when it cometh, then ye shall know that I [am] the Lord Jehovah.", "twenty": "", "jps": "Thus shall Ezekiel be unto you a sign; according to all that he hath done shall ye do; when this cometh, then shall ye know that I am the L-rd GOD.", "acv": "Thus Ezekiel shall be to you a sign, according to all that he has done ye shall do. When this comes, then ye shall know that I am the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus Ezekiel shall be to you a sign; according to all that he hath done shall ye do, when this cometh; and ye shall know that I am the Lord Jehovah.", "webster": "Thus Ezekiel is to you a sign: according to all that he hath done shall ye do: and when this cometh, ye shall know that I [am] the Lord GOD.", "vulgate": "eritque Hiezecihel vobis in portentum iuxta omnia quae fecit facietis cum venerit istud et scietis quia ego Dominus Deus;", "brenton": "And Jezekiel shall be for a sign to you: according to all that I have done shall ye do, when these things shall come; and ye shall know that I am the Lord."}}, {"v": 25, "ref": "24:25", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם הֲ/ל֗וֹא בְּ/י֨וֹם קַחְתִּ֤/י מֵ/הֶם֙ אֶת מָ֣עוּזָּ֔/ם מְשׂ֖וֹשׂ תִּפְאַרְתָּ֑/ם אֶת מַחְמַ֤ד עֵֽינֵי/הֶם֙ וְ/אֶת מַשָּׂ֣א נַפְשָׁ֔/ם בְּנֵי/הֶ֖ם וּ/בְנוֹתֵי/הֶֽם", "en": {"kjv": "Also, thou son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that whereupon they set their minds, their sons and their daughters,", "web": "You, son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that whereupon they set their heart, their sons and their daughters,", "bsb": "And you, son of man, know that on the day I take away their stronghold, their pride and joy—the desire of their eyes which uplifted their souls—and their sons and daughters as well,", "asv": "And thou, son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that whereupon they set their heart, their sons and their daughters,", "ylt": "And thou, son of man, Is it not in the day of My taking from them their strength, The joy of their beauty, the desire of their eyes, And the song of their soul, Their sons and their daughters?", "dra": "And thou, O son of man, behold in the day wherein I will take away from them their strength, and the joy of their glory, and the desire of their eyes, upon which their souls rest, their sons and their daughters.", "bbe": "And as for you, son of man, your mouth will be shut in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that on which their hearts are fixed, and their sons and daughters.", "geneva": "Also, thou sonne of man, shall it not be in the day when I take from them their power, ye ioy of their honor, ye pleasure of their eyes, and the desire of their heart, their sonnes and their daughters?", "wycliffe": "And thou, sone of man, lo! in the dai in which Y schal take awei fro hem the strengthe of hem, and the ioie of dignyte, and the desire of her iyen, on whiche the soulis of hem resten, caste awei the sones and douytris of hem;", "rotherham": "Thou, therefore Son of man, Shall it not be— In the day when I take away from them Their strength, The joy of their adorning,— The delight of their eyes And the desire of their soul, Their sons and their daughters", "darby": "And thou, son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that whereunto they lift up their soul, their sons and their daughters,", "twenty": "", "jps": "And thou, son of man, shall it not be in the day when I take from them their stronghold, the joy of their glory, the desire of their eyes, and the yearning of their soul, their sons and their daughters,", "acv": "And thou, son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that upon which they set their heart-their sons and their daughters-", "anderson": "", "haweis": "", "noyes": "And thou, son of man, behold, in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and the longing of their souls, their sons and their daughters, in that day shall one", "webster": "Also, thou son of man, [shall it] not [be] in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that on which they set their minds, their sons and their daughters,", "vulgate": "et tu fili hominis ecce in die quo tollam ab eis fortitudinem eorum et gaudium dignitatis et desiderium oculorum eorum super quo requiescunt animae eorum filios et filias eorum;", "brenton": "And thou, son of man, shall it not be in the day when I take their strength from them, the pride of their boasting, the desires of their eyes, and the pride of their soul, their sons and their daughters,"}}, {"v": 26, "ref": "24:26", "o": "בַּ/יּ֣וֹם הַ/ה֔וּא יָב֥וֹא הַ/פָּלִ֖יט אֵלֶ֑י/ךָ לְ/הַשְׁמָע֖וּת אָזְנָֽיִם", "en": {"kjv": "That he that escapeth in that day shall come unto thee, to cause thee to hear it with thine ears?", "web": "that in that day he who escapes shall come to you, to cause you to hear it with your ears?", "bsb": "on that day a fugitive will come and tell you the news.", "asv": "that in that day he that escapeth shall come unto thee, to cause thee to hear it with thine ears?", "ylt": "In that day come doth the escaped one to thee. To cause the ears to hear.", "dra": "In that day when he that escapeth shall come to thee, to tell thee:", "bbe": "In that day, one who has got away safe will come to you to give you news of it.", "geneva": "That he that escapeth in that day, shall come vnto thee to tell thee that which hee hath heard with his eares?", "wycliffe": "in that dai whanne a man fleynge schal come to thee, to telle to thee;", "rotherham": "That in that day, one that hath escaped shall come in unto thee,—to cause thee to hear it with thine own ears?", "darby": "that in that day he that escapeth shall come unto thee, to cause [thine] ears to hear [it]?", "twenty": "", "jps": "that in that day he that escapeth shall come unto thee, to cause thee to hear it with thine ears?", "acv": "that in that day he who escapes shall come to thee, to cause thee to hear it with thine ears?", "anderson": "", "haweis": "", "noyes": "that is escaped come to thee, to cause thee to hear it with thine ears.", "webster": "[That] he that escapeth in that day shall come to thee, to cause [thee] to hear [it] with [thy] ears?", "vulgate": "in die illa cum venerit fugiens ad te ut adnuntiet tibi;", "brenton": "that in that day he that escapes shall come to thee, to tell it thee in thine ears?"}}, {"v": 27, "ref": "24:27", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יִפָּ֤תַח פִּ֨י/ךָ֙ אֶת הַ/פָּלִ֔יט וּ/תְדַבֵּ֕ר וְ/לֹ֥א תֵֽאָלֵ֖ם ע֑וֹד וְ/הָיִ֤יתָ לָ/הֶם֙ לְ/מוֹפֵ֔ת וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "In that day shall thy mouth be opened to him which is escaped, and thou shalt speak, and be no more dumb: and thou shalt be a sign unto them; and they shall know that I am the Lord.", "web": "In that day your mouth will be opened to him who has escaped, and you shall speak, and be no more mute: so you will be a sign to them; and they shall know that I am Yahweh.", "bsb": "On that day your mouth will be opened to him who has escaped; you will speak and no longer be mute. So you will be a sign to them, and they will know that I am the LORD.”", "asv": "In that day shall thy mouth be opened to him that is escaped, and thou shalt speak, and be no more dumb: so shalt thou be a sign unto them; and they shall know that I am Jehovah.", "ylt": "In that day opened is thy mouth with the escaped, And thou speakest, and art not silent any more, And thou hast been to them for a type. And they have known that I am Jehovah.'", "dra": "In that day, I say, shall thy mouth be opened to him that hath escaped, and thou shalt speak, and shalt be silent no more: and thou shalt be unto them for a sign of things to come, and you shall know that I am the Lord.", "bbe": "In that day your mouth will be open to him who has got away safe, and you will say words to him and your lips will no longer be shut: so you will be a sign to them and they will be certain that I am the Lord.", "geneva": "In that day shall thy mouth be opened to him which is escaped, and thou shalt speake, and be no more dumme, and thou shalt be a signe vnto them, and they shall knowe that I am the Lord.", "wycliffe": "in that dai sotheli thou schalt opene thi mouth with hym that fledde; and thou schalt speke, and schalt no more be stille; and thou schalt be to hem in to a signe of thing to comynge, and ye schulen witen, that Y am the Lord.", "rotherham": "That in that day, thy mouth shall be opened unto him that hath escaped, And thou shalt speak and not be dumb any longer? So shalt thou become to them a wonder, And they shall know that, I, am Yahweh.", "darby": "In that day shall thy mouth be opened to him that is escaped, and thou shalt speak, and be no more dumb. So shalt thou be a sign unto them; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "In that day shall thy mouth be opened together with him that is escaped, and thou shalt speak, and be no more dumb; so shalt thou be a sign unto them; and they shall know that I am HaShem.'", "acv": "In that day thy mouth shall be opened to him who is escaped, and thou shall speak, and no more be mute. So thou shall be a sign to them, and they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "In that day shall thy mouth be opened to him that is escaped, and thou shalt speak, and be no more dumb; and thou shalt be a sign to them, and they shall know that I am Jehovah.", "webster": "In that day shall thy mouth be opened to him who hath escaped, and thou shalt speak, and be no more dumb: and thou shalt be a sign to them; and they shall know that I [am] the LORD.", "vulgate": "in die inquam illa aperietur os tuum cum eo qui fugit et loqueris et non silebis ultra erisque eis in portentum et scietis quia ego Dominus;", "brenton": "In that day thy mouth shall be opened to him that escapes; thou shalt speak, and shalt be no longer dumb: and thou shalt be for a sign to them, and they shall know that I am the Lord."}}]}, {"c": 25, "verses": [{"v": 1, "ref": "25:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "The worde of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came again to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "25:2", "o": "בֶּן אָדָ֕ם שִׂ֥ים פָּנֶ֖י/ךָ אֶל בְּנֵ֣י עַמּ֑וֹן וְ/הִנָּבֵ֖א עֲלֵי/הֶֽם", "en": {"kjv": "Son of man, set thy face against the Ammonites, and prophesy against them;", "web": "Son of man, set your face toward the children of Ammon, and prophesy against them:", "bsb": "“Son of man, set your face against the Ammonites and prophesy against them.", "asv": "Son of man, set thy face toward the children of Ammon, and prophesy against them:", "ylt": "`Son of man, set thy face unto the sons of Ammon, and prophesy against them;", "dra": "Son of man, set thy face against the children of Ammon, and thou shalt prophesy of them.", "bbe": "Son of man, let your face be turned to the children of Ammon, and be a prophet against them:", "geneva": "Sonne of man, set thy face against the Ammonites, and prophecie against them,", "wycliffe": "and he seide, Thou, sone of man, sette thi face ayens the sones of Amon, and thou schalt profesie of hem.", "rotherham": "Son of man Set thy face against the sons of Ammon,— and prophesy against them.", "darby": "Son of man, set thy face against the children of Ammon, and prophesy against them;", "twenty": "", "jps": "'Son of man, set thy face toward the children of Ammon, and prophesy against them;", "acv": "Son of man, set thy face toward the sons of Ammon, and prophesy against them.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against the Ammonites, and prophesy against them;", "webster": "Son of man, set thy face against the Ammonites, and prophesy against them;", "vulgate": "fili hominis pone faciem tuam contra filios Ammon et prophetabis de eis;", "brenton": "Son of man, set thy face steadfastly against the children of Ammon, and prophesy against them;"}}, {"v": 3, "ref": "25:3", "o": "וְ/אָֽמַרְתָּ֙ לִ/בְנֵ֣י עַמּ֔וֹן שִׁמְע֖וּ דְּבַר אֲדֹנָ֣/י יְהוִ֑ה כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֡ה יַעַן֩ אָמְרֵ֨/ךְ הֶאָ֜ח אֶל מִקְדָּשִׁ֣/י כִֽי נִחָ֗ל וְ/אֶל אַדְמַ֤ת יִשְׂרָאֵל֙ כִּ֣י נָשַׁ֔מָּה וְ/אֶל בֵּ֣ית יְהוּדָ֔ה כִּ֥י הָלְכ֖וּ בַּ/גּוֹלָֽה", "en": {"kjv": "And say unto the Ammonites, Hear the word of the Lord God; Thus saith the Lord God; Because thou saidst, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was desolate; and against the house of Judah, when they went into captivity;", "web": "and tell the children of Ammon, Hear the word of the Lord Yahweh: Thus says the Lord Yahweh, Because you said, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was made desolate; and against the house of Judah, when they went into captivity:", "bsb": "Tell the Ammonites to hear the word of the Lord GOD, for this is what the Lord GOD says: ‘Because you exclaimed, “Aha!” when My sanctuary was profaned, when the land of Israel was laid waste, and when the house of Judah went into exile,", "asv": "and say unto the children of Ammon, Hear the word of the Lord Jehovah: Thus saith the Lord Jehovah, Because thou saidst, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was made desolate; and against the house of Judah, when they went into captivity:", "ylt": "and thou hast said to the sons of Ammon: Hear ye a word of the Lord Jehovah: Thus said the Lord Jehovah: Because of thy saying, Aha, to My sanctuary, Because it hath been polluted, And unto the ground of Israel, Because it hath been desolate, And unto the house of Judah, Because they have gone into a removal:", "dra": "And thou shalt say to the children of Ammon: Hear ye the word of the Lord God: Thus saith the Lord God: Because thou hast said: Ha, ha, upon my sanctuary, because it was profaned: and upon the land of Israel, because it was laid waste: and upon the house of Juda, because they are led into captivity:", "bbe": "And say to the children of Ammon, Give ear to the word of the Lord; this is what the Lord has said: Because you said, Aha! against my holy place when it was made unclean, and against the land of Israel when it was made waste, and against the people of Judah when they were taken away as prisoners;", "geneva": "And say vnto the Ammonites, Heare the word of the Lord God, Thus saith the Lord God, Because thou saydest, Ha, ha, against my Sanctuarie, when it was polluted, and against the land of Israel, when it was desolate, and against the house of Iudah, when they went into captiuitie,", "wycliffe": "And thou schalt seie to the sones of Amon, Here ye the word of the Lord God; the Lord God seith these thingis, For that that ye seiden, Wel! wel! on my seyntuarie, for it is defoulid, and on the lond of Israel, for it is maad desolat, and on the hous of Juda, for thei ben led in to to caitifte; lo!", "rotherham": "So then thou shalt say to the sons of Ammon, Hear ye the word of My Lord Yahweh: Thus, saith My Lord. Yahweh: Because thou saidst Aha! Against my sanctuary when it was profaned. And against the soil of Israel when it was laid waste, And against the house of Judah when they went into exile.", "darby": "and say unto the children of Ammon, Hear the word of the Lord Jehovah. Thus saith the Lord Jehovah: Because thou saidst, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was made desolate; and against the house of Judah, when they went into captivity:", "twenty": "", "jps": "and say unto the children of Ammon: Hear the word of the L-rd GOD: Thus saith the L-rd GOD: Because thou saidst: Aha! against My sanctuary, when it was profaned, and against the land of Israel, when it was made desolate, and against the house of Judah, when they went into captivity;", "acv": "And say to the sons of Ammon, Hear the word of the lord Jehovah. Thus says the lord Jehovah: Because thou said, Aha, against my sanctuary when it was profaned, and against the land of Israel when it was made desolate, and against the house of Judah when they went into captivity,", "anderson": "", "haweis": "", "noyes": "and say to the Ammonites, Hear the word of the Lord Jehovah! Thus saith the Lord Jehovah: Because thou saidst, \"Aha!\" against my sanctuary when it was profaned, and against the land of Israel when it was desolate, and against the house of Judah when they went into captivity, therefore,", "webster": "And say to the Ammonites, Hear the word of the Lord GOD; Thus saith the Lord GOD; Because thou saidst, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was desolate; and against the house of Judah, when they went into captivity;", "vulgate": "et dices filiis Ammon audite verbum Domini Dei haec dicit Dominus Deus pro eo quod dixisti euge euge super sanctuarium meum quia pollutum est et super terram Israhel quoniam desolata est et super domum Iuda quoniam ducti sunt in captivitatem;", "brenton": "and thou shalt say to the children of Ammon, Hear ye the word of the Lord; thus saith the Lord; Forasmuch as ye have rejoiced against my sanctuary, because it was profaned; and against the land of Israel, because it was laid waste; and against the house of Juda, because they went into captivity;"}}, {"v": 4, "ref": "25:4", "o": "לָ/כֵ֡ן הִנְ/נִי֩ נֹתְנָ֨/ךְ לִ/בְנֵי קֶ֜דֶם לְ/מֽוֹרָשָׁ֗ה וְ/יִשְּׁב֤וּ טִירֽוֹתֵי/הֶם֙ בָּ֔/ךְ וְ/נָ֥תְנוּ בָ֖/ךְ מִשְׁכְּנֵי/הֶ֑ם הֵ֚מָּה יֹאכְל֣וּ פִרְיֵ֔/ךְ וְ/הֵ֖מָּה יִשְׁתּ֥וּ חֲלָבֵֽ/ךְ", "en": {"kjv": "Behold, therefore I will deliver thee to the men of the east for a possession, and they shall set their palaces in thee, and make their dwellings in thee: they shall eat thy fruit, and they shall drink thy milk.", "web": "therefore, behold, I will deliver you to the children of the east for a possession, and they shall set their encampments in you, and make their dwellings in you; they shall eat your fruit, and they shall drink your milk.", "bsb": "therefore I will indeed give you as a possession to the people of the East. They will set up their camps and pitch their tents among you. They will eat your fruit and drink your milk.", "asv": "therefore, behold, I will deliver thee to the children of the east for a possession, and they shall set their encampments in thee, and make their dwellings in thee; they shall eat thy fruit, and they shall drink thy milk.", "ylt": "Therefore, lo, I am giving thee to sons of the east for a possession, And they set their towers in thee, And have placed in thee their tabernacles. They eat thy fruit, and they drink thy milk,", "dra": "Therefore will I deliver thee to the men of the east for an inheritance, and they shall place their sheepcotes in thee, and shall set up their tents in thee: they shall eat thy fruits: and they shall drink thy milk.", "bbe": "For this cause I will give you up to the children of the east for their heritage, and they will put their tent-circles in you and make their houses in you; they will take your fruit for their food and your milk for their drink.", "geneva": "Beholde, therefore I will deliuer thee to the men of the East for a possession, and they shall set their palaces in thee, and make their dwellings in thee: they shall eate thy fruite, and they shall drinke thy milke.", "wycliffe": "therfor Y schal yyue thee the sones of the eest in to eritage, and thei schulen sette her foldis in thee, and thei shulen sette her tentis in thee; thei schulen ete thi fruytis, and thei schulen drynke thi mylk.", "rotherham": "Therefore, behold me! delivering thee up to the Sons of the East for a possession And they shall set their encampments in thee, And place in thee their habitations, They, shall eat thy fruits, And they, shall drink thy milk;", "darby": "therefore behold, I will give thee to the children of the east for a possession, and they shall set their encampments in thee, and make their dwellings in thee; they shall eat thy fruits, and they shall drink thy milk.", "twenty": "", "jps": "therefore, behold, I will deliver thee to the children of the east for a possession, and they shall set their encampments in thee, and make their dwellings in thee; they shall eat thy fruit, and they shall drink thy milk.", "acv": "therefore, behold, I will deliver thee to the sons of the east for a possession, and they shall set their encampments in thee, and make their dwellings in thee. They shall eat thy fruit, and they shall drink thy milk.", "anderson": "", "haweis": "", "noyes": "behold, I will deliver thee to the sons of the East for a possession, and they shall set their folds in thee, and make their dwellings in thee; they shall eat thy fruit, and they shall drink thy milk.", "webster": "Behold, therefore I will deliver thee to the men of the east for a possession, and they shall set their palaces in thee, and make their dwellings in thee: they shall eat thy fruit, and they shall drink thy milk.", "vulgate": "idcirco ego tradam te filiis orientalibus in hereditatem et conlocabunt caulas suas in te et ponent in te tentoria sua ipsi comedent fruges tuas et ipsi bibent lac tuum;", "brenton": "therefore, behold, I will deliver you to the children of Kedem for an inheritance, and they shall lodge in thee with their stuff, and they shall pitch their tents in thee: they shall eat thy fruits, and they shall drink thy milk."}}, {"v": 5, "ref": "25:5", "o": "וְ/נָתַתִּ֤י אֶת רַבָּה֙ לִ/נְוֵ֣ה גְמַלִּ֔ים וְ/אֶת בְּנֵ֥י עַמּ֖וֹן לְ/מִרְבַּץ צֹ֑אן וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will make Rabbah a stable for camels, and the Ammonites a couchingplace for flocks: and ye shall know that I am the Lord.", "web": "I will make Rabbah a stable for camels, and the children of Ammon a resting place for flocks: and you shall know that I am Yahweh.", "bsb": "I will make Rabbah a pasture for camels, and Ammon a resting place for sheep. Then you will know that I am the LORD.’", "asv": "And I will make Rabbah a stable for camels, and the children of Ammon a couching-place for flocks: and ye shall know that I am Jehovah.", "ylt": "And I have given Rabbah for a habitation of camels, And the sons of Ammon for the crouching of a flock, And ye have known that I am Jehovah.", "dra": "And I will make Rabbath a stable for camels, and the children of Ammon a couching place for flocks: and you shall know that I am the Lord.", "bbe": "And I will make Rabbah a place for housing camels, and the children of Ammon a resting-place for flocks: and you will be certain that I am the Lord.", "geneva": "And I will make Rabbah a dwelling place for camels, and the Ammonites a sheepecote, and ye shall knowe that I am the Lord.", "wycliffe": "And Y schal yyue Rabath in to a dwellyng place of camels, and the sones of Amon in to a bed of beestis; and ye schulen wite, that Y am the Lord.", "rotherham": "And I will make of Rabbah a home for camels, And the sons of Ammon a couching-place for flocks, So shall ye know that, I, am Yahweh.", "darby": "And I will make Rabbah a pasture for camels, and the children of Ammon a couching-place for flocks: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "And I will make Rabbah a pasture for camels, and the children of Ammon a couching-place for flocks; and ye shall know that I am HaShem.", "acv": "And I will make Rabbah a stable for camels, and the sons of Ammon a couching-place for flocks. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will make Rabbah a stable for camels, and the land of the Ammonites a couching-place for flocks; and ye shall know that I am Jehovah.", "webster": "And I will make Rabbah a stable for camels, and the Ammonites a couching-place for flocks: and ye shall know that I [am] the LORD.", "vulgate": "daboque Rabbath in habitaculum camelorum et filios Ammon in cubile pecorum et scietis quia ego Dominus;", "brenton": "And I will give up the city of Ammon for camels' pastures, and the children of Ammon for a pasture of sheep: and ye shall know that I am the Lord."}}, {"v": 6, "ref": "25:6", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֚עַן מַחְאֲ/ךָ֣ יָ֔ד וְ/רַקְעֲ/ךָ֖ בְּ/רָ֑גֶל וַ/תִּשְׂמַ֤ח בְּ/כָל שָֽׁאטְ/ךָ֙ בְּ/נֶ֔פֶשׁ אֶל אַדְמַ֖ת יִשְׂרָאֵֽל", "en": {"kjv": "For thus saith the Lord God; Because thou hast clapped thine hands, and stamped with the feet, and rejoiced in heart with all thy despite against the land of Israel;", "web": "For thus says the Lord Yahweh: Because you have clapped your hands, and stamped with the feet, and rejoiced with all the despite of your soul against the land of Israel;", "bsb": "For this is what the Lord GOD says: ‘Because you clapped your hands and stomped your feet and rejoiced over the land of Israel with a heart full of contempt,", "asv": "For thus saith the Lord Jehovah: Because thou hast clapped thy hands, and stamped with the feet, and rejoiced with all the despite of thy soul against the land of Israel;", "ylt": "For thus said the Lord Jehovah: Because of thy clapping the hand, And of thy stamping with the foot, And thou rejoicest with all thy despite in soul Against the ground of Israel,", "dra": "For thus saith the Lord God: Because thou hast clapped thy hands and stamped with thy foot, and hast rejoiced with all thy heart against the land of Israel:", "bbe": "For the Lord has said, Because you have made sounds of joy with your hands, stamping your feet, and have been glad, putting shame with all your soul on the land of Israel;", "geneva": "For thus saith the Lord God, Because thou hast clapped the hands, and stamped with the feete, and reioyced in heart with all thy despite against the land of Israel,", "wycliffe": "For the Lord God seith these thingis, For that that thou flappidist with hond, and smytidist with the foot, and ioyedist of al desijr on the lond of Israel;", "rotherham": "For, thus, saith My Lord Yahweh, Because thou didst clap thy hands and stamp with thy foot,—and didst rejoice with all thy contempt in thy soul, against the soil of Israel.", "darby": "For thus saith the Lord Jehovah: Because thou hast clapped the hands, and stamped with the feet, and rejoiced with all the despite of thy soul against the land of Israel;", "twenty": "", "jps": "For thus saith the L-rd GOD: Because thou hast clapped thy hands, and stamped with the feet, and rejoiced with all the disdain of thy soul against the land of Israel;", "acv": "For thus says the lord Jehovah: Because thou have clapped thy hands, and stamped with the feet, and rejoiced with all the spite of thy soul against the land of Israel,", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: Because thou hast clapped thy hands, and stamped with thy feet, and rejoiced with all thy despite from the heart, against the land of Israel,", "webster": "For thus saith the Lord GOD; Because thou hast clapped [thy] hands, and stamped with the feet, and rejoiced in heart with all thy despite against the land of Israel;", "vulgate": "quia haec dicit Dominus Deus pro eo quod plausisti manu et percussisti pede et gavisa es ex toto affectu super terram Israhel;", "brenton": "For thus saith the Lord; Because thou hast clapped thine hands, and stamped with thy foot, and heartily rejoiced against the land of Israel;"}}, {"v": 7, "ref": "25:7", "o": "לָ/כֵ֡ן הִנְ/נִי֩ נָטִ֨יתִי אֶת יָדִ֜/י עָלֶ֗י/ךָ וּ/נְתַתִּ֤י/ךָֽ ל/בג לְ/בַז֙ לַ/גּוֹיִ֔ם וְ/הִכְרַתִּ֨י/ךָ֙ מִן הָ֣/עַמִּ֔ים וְ/הַאֲבַדְתִּ֖י/ךָ מִן הָ/אֲרָצ֑וֹת אַשְׁמִ֣ידְ/ךָ֔ וְ/יָדַעְתָּ֖ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Behold, therefore I will stretch out mine hand upon thee, and will deliver thee for a spoil to the heathen; and I will cut thee off from the people, and I will cause thee to perish out of the countries: I will destroy thee; and thou shalt know that I am the Lord.", "web": "therefore, behold, I have stretched out my hand on you, and will deliver you for a plunder to the nations; and I will cut you off from the peoples, and I will cause you to perish out of the countries: I will destroy you; and you shall know that I am Yahweh.", "bsb": "therefore I will indeed stretch out My hand against you and give you as plunder to the nations. I will cut you off from the peoples and exterminate you from the countries. I will destroy you, and you will know that I am the LORD.’", "asv": "therefore, behold, I have stretched out my hand upon thee, and will deliver thee for a spoil to the nations; and I will cut thee off from the peoples, and I will cause thee to perish out of the countries: I will destroy thee; and thou shalt know that I am Jehovah.", "ylt": "Therefore, lo, I--I have stretched out My hand against thee, And have given thee for a portion to nations, And I have cut thee off from the peoples, And caused thee to perish from the lands; I destroy thee, and thou hast known that I am Jehovah.", "dra": "Therefore behold I will stretch forth my hand upon thee, and will deliver thee to be the spoil of nations, and will cut thee off from among the people, and destroy thee out of the lands, and break thee in pieces: and thou shalt know that I am the Lord.", "bbe": "For this cause my hand has been stretched out against you, and I will give up your goods to be taken by the nations; I will have you cut off from the peoples and will put an end to you among the countries: I will give you up to destruction; and you will be certain that I am the Lord.", "geneva": "Beholde, therefore I will stretche out mine hand vpon thee, and will deliuer thee to be spoyled of the heathen, and I will roote thee out from the people, and I will cause thee to be destroyed out of the countreys, and I will destroy thee, and thou shalt know that I am the Lord.", "wycliffe": "therfor lo! Y schal stretche forth myn hond on thee, and Y schal yyue thee in to rauyschyng of hethene men, and Y schal sle thee fro puplis, and Y schal leese thee, and al to-breke thee fro londis; and ye schulen wite, that Y am the Lord.", "rotherham": "Therefore behold me! I have stretched out my hand over thee And will deliver thee for a prey to the nations, And will cut thee off from among the peoples, And will cause thee to perish from among the lands,— I will destroy thee, So shalt thou know that, I, am Yahweh.", "darby": "therefore behold, I will stretch out my hand upon thee, and will give thee for a spoil to the nations; and I will cut thee off from the peoples, and I will cause thee to perish out of the countries: I will destroy thee, and thou shalt know that I [am] Jehovah.", "twenty": "", "jps": "therefore, behold, I stretch out My hand upon thee, and will deliver thee for a spoil to the nations; and I will cut thee off from the peoples, and I will cause thee to perish out of the countries; I will destroy thee, and thou shalt know that I am HaShem.", "acv": "therefore, behold, I have stretched out my hand upon thee, and will deliver thee for a spoil to the nations. And I will cut thee off from the peoples, and I will cause thee to perish out of the countries. I will destroy thee, and thou shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "therefore, behold, I will stretch out my hand upon thee, and will deliver thee for a spoil to the nations; I will cut thee off from the nations, and cause thee to perish from the countries; I will destroy thee; and thou shalt know that I am Jehovah.", "webster": "Behold, therefore I will stretch out my hand upon thee, and will deliver thee for a spoil to the heathen; and I will cut thee off from the people, and I will cause thee to perish out of the countries: I will destroy thee; and thou shalt know that I [am] the LORD.", "vulgate": "idcirco ecce ego extendam manum meam super te et tradam te in direptionem gentium et interficiam te de populis et perdam de terris et conteram et scies quia ego Dominus;", "brenton": "therefore I will stretch out my hand against thee, and I will make thee a spoil to the nations; and I will utterly destroy thee from among the peoples, and I will completely cut thee off from out of the countries: and thou shalt know that I am the Lord."}}, {"v": 8, "ref": "25:8", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה יַ֗עַן אֲמֹ֤ר מוֹאָב֙ וְ/שֵׂעִ֔יר הִנֵּ֥ה כְּ/כָֽל הַ/גּוֹיִ֖ם בֵּ֥ית יְהוּדָֽה", "en": {"kjv": "Thus saith the Lord God; Because that Moab and Seir do say, Behold, the house of Judah is like unto all the heathen;", "web": "Thus says the Lord Yahweh: Because Moab and Seir say, Behold, the house of Judah is like all the nations;", "bsb": "This is what the Lord GOD says: ‘Because Moab and Seir said, “Look, the house of Judah is like all the other nations,”", "asv": "Thus saith the Lord Jehovah: Because that Moab and Seir do say, Behold, the house of Judah is like unto all the nations;", "ylt": "Thus said the Lord Jehovah: Because of the saying of Moab and Seir: Lo, as all the nations is the house of Judah;", "dra": "Thus saith the Lord God: Because Moab and Seir have said: Behold the house of Juda is like all other nations:", "bbe": "This is what the Lord has said: Because Moab and Seir are saying, See, the people of Judah are like all the nations;", "geneva": "Thus saith the Lord God, Because that Moab and Seir doe say, Beholde, the house of Iudah is like vnto all the heathen,", "wycliffe": "The Lord God seith these thingis, For that that Moab and Seir seiden, Lo! the hous of Juda is as alle folkis; therfor lo!", "rotherham": "Thus saith My Lord Yahweh: Because Moab and Seir say, Lo! like all the nations, is the house of Judah.", "darby": "Thus saith the Lord Jehovah: Because Moab and Seir do say, Behold, the house of Judah is like unto all the nations,", "twenty": "", "jps": "Thus saith the L-rd GOD: Because that Moab and Seir do say: Behold, the house of Judah is like unto all the nations,", "acv": "Thus says the lord Jehovah: Because Moab and Seir say, Behold, the house of Judah is like all the nations,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because Moab and Seir say, \"Behold, the house of Judah is like all the nations,\"", "webster": "Thus saith the Lord GOD; Because that Moab and Seir do say, Behold, the house of Judah [is] like all the heathen;", "vulgate": "haec dicit Dominus Deus pro eo quod dixerunt Moab et Seir ecce sicut omnes gentes domus Iuda;", "brenton": "Thus saith the Lord; Because Moab has said, Behold, are not the house of Israel and Juda like all the other nations?"}}, {"v": 9, "ref": "25:9", "o": "לָ/כֵן֩ הִנְ/נִ֨י פֹתֵ֜חַ אֶת כֶּ֤תֶף מוֹאָב֙ מֵ/הֶ֣/עָרִ֔ים מֵֽ/עָרָ֖י/ו מִ/קָּצֵ֑/הוּ צְבִ֗י אֶ֚רֶץ בֵּ֣ית הַיְשִׁימֹ֔ת בַּ֥עַל מְע֖וֹן ו/קריתמ/ה וְ/קִרְיָתָֽיְמָ/ה", "en": {"kjv": "Therefore, behold, I will open the side of Moab from the cities, from his cities which are on his frontiers, the glory of the country, Beth–jeshimoth, Baal–meon, and Kiriathaim,", "web": "therefore, behold, I will open the side of Moab from the cities, from his cities which are on his frontiers, the glory of the country, Beth Jeshimoth, Baal Meon, and Kiriathaim,", "bsb": "therefore I will indeed expose the flank of Moab beginning with its frontier cities—Beth-jeshimoth, Baal-meon, and Kiriathaim—the glory of the land.", "asv": "therefore, behold, I will open the side of Moab from the cities, from his cities which are on his frontiers, the glory of the country, Beth-jeshimoth, Baal-meon, and Kiriathaim,", "ylt": "Therefore, lo, I am opening the shoulder of Moab--From the cities--from his cities--from his frontier, The beauty of the land, Beth-Jeshimoth, Baal-Meon, and Kiriathaim,", "dra": "Therefore behold I will open the shoulder of Moab from the cities, from his cities, I say, and his borders, the noble cities of the land of Bethiesimoth, and Beelmeon, and Cariathaim,", "bbe": "For this cause, I will let the side of Moab be uncovered, and his towns on every side, the glory of the land, Beth-jeshimoth, Baal-meon and as far as Kiriathaim.", "geneva": "Therefore, beholde, I will open the side of Moab, euen of the cities of his cities, I say, in his frontiers with the pleasant countrey, Beth-ieshimoth, Baal-meon, and Karia-thaim.", "wycliffe": "Y schal opene the schuldre of Moab of citees, sotheli of citees therof and of the endis therof, the noble citees of the lond, Bethiesmoth, and Beelmoth,", "rotherham": "Therefore, behold me! laying open the side of Moab out of the cities, Out of his cities on his frontiers, The beauty of the land of Beth-jeshimoth, Baal-meon, and Kiriathaim:", "darby": "therefore behold, I will open the side of Moab from the cities, from his cities even to the last of them, the glory of the country, Beth-jeshimoth, Baal-meon, and Kirjathaim,", "twenty": "", "jps": "therefore, behold, I will open the flank of Moab on the side of the cities, on the side of his cities which are on his frontiers, the beauteous country of Beth-jeshimoth, Baal-meon, and Kiriathaim,", "acv": "therefore, behold, I will open the side of Moab from the cities, from his cities which are on his frontiers, the glory of the country-Beth-jeshimoth, Baal-meon, and Kiriathaim-", "anderson": "", "haweis": "", "noyes": "therefore, behold, I will open the side of Moab from his cities, which are on his borders, the glory of the country, Beth-jeshimoth, Baal-meon, and Kiriathaim.", "webster": "Therefore behold, I will open the side of Moab from the cities, from his cities [which are] on his frontiers, the glory of the country, Beth-jeshimoth, Baal-meon, and Kiriathaim,", "vulgate": "idcirco ecce ego aperiam umerum Moab de civitatibus de civitatibus inquam eius et de finibus eius inclitas terrae Bethiesimoth et Beelmeon et Cariathaim;", "brenton": "Therefore, behold, I will weaken the shoulder of Moab from his frontier cities, even the choice land, the house of Bethasimuth above the fountain of the city, by the sea-side."}}, {"v": 10, "ref": "25:10", "o": "לִ/בְנֵי קֶ֨דֶם֙ עַל בְּנֵ֣י עַמּ֔וֹן וּ/נְתַתִּ֖י/הָ לְ/מֽוֹרָשָׁ֑ה לְמַ֛עַן לֹֽא תִזָּכֵ֥ר בְּנֵֽי עַמּ֖וֹן בַּ/גּוֹיִֽם", "en": {"kjv": "Unto the men of the east with the Ammonites, and will give them in possession, that the Ammonites may not be remembered among the nations.", "web": "to the children of the east, to go against the children of Ammon; and I will give them for a possession, that the children of Ammon may not be remembered among the nations.", "bsb": "I will give it along with the Ammonites as a possession to the people of the East, so that the Ammonites will no longer be remembered among the nations.", "asv": "unto the children of the east, to go against the children of Ammon; and I will give them for a possession, that the children of Ammon may not be remembered among the nations:", "ylt": "To the sons of the east, with the sons of Ammon, And I have given it for a possession, So that the sons of Ammon are not remembered among nations.", "dra": "To the people of the east with the children of Ammon, and I will give it them for an inheritance: that there may be no more any remembrance of the children of Ammon among the nations.", "bbe": "To the children of the east I have given her for a heritage, as well as the children of Ammon, so that there may be no memory of her among the nations:", "geneva": "I will call the men of the East against the Ammonites, and will giue them in possession, so that the Ammonites shall no more be remembred among the nations,", "wycliffe": "and Cariathaym, to the sones of the eest, with the sones of Amon. And Y schal yyue it in to eritage, that mynde of the sones of Amon be no more among hethene men,", "rotherham": "To the Sons of the East [when they come] against the sons of Ammon, and I will deliver it up for possession,-to the end the sons of Ammon may not be remembered among the nations:", "darby": "unto the children of the east, with [the land of] the children of Ammon; and I will give it them for a possession, that the children of Ammon may not be remembered among the nations:", "twenty": "", "jps": "together with the children of Ammon, unto the children of the east, and I will give them for a possession, that the children of Ammon may not be remembered among the nations;", "acv": "open to the sons of the east, against the sons of Ammon. And I will give them for a possession, that the sons of Ammon may not be remembered among the nations.", "anderson": "", "haweis": "", "noyes": "To the sons of the East will I give it for a possession, together with the sons of Ammon, that the sons of Ammon may be no more remembered among the nations;", "webster": "To the men of the east with the Ammonites, and will give them in possession, that the Ammonites may not be remembered among the nations.", "vulgate": "filiis orientis cum filiis Ammon et dabo eam in hereditatem ut non sit memoria ultra filiorum Ammon in gentibus;", "brenton": "I have given him the children of Kedem in addition to the children of Ammon for an inheritance, that there may be no remembrance of the children of Ammon."}}, {"v": 11, "ref": "25:11", "o": "וּ/בְ/מוֹאָ֖ב אֶעֱשֶׂ֣ה שְׁפָטִ֑ים וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will execute judgments upon Moab; and they shall know that I am the Lord.", "web": "and I will execute judgments on Moab; and they shall know that I am Yahweh.", "bsb": "So I will execute judgments on Moab, and they will know that I am the LORD.’", "asv": "and I will execute judgments upon Moab; and they shall know that I am Jehovah.", "ylt": "And in Moab I do judgments, And they have known that I am Jehovah.", "dra": "And I will execute judgments in Moab: and they shall know that I am the Lord.", "bbe": "And I will be the judge of Moab; and they will see that I am the Lord.", "geneva": "And I will execute iudgements vpon Moab, and they shall knowe that I am the Lord.", "wycliffe": "and in Moab Y schal make domes; and thei schulen wite, that Y am the Lord.", "rotherham": "Also upon Moab, will I execute judgments,- So shall they know that I, am Yahweh.", "darby": "and I will execute judgments upon Moab, and they shall know that I [am] Jehovah.", "twenty": "", "jps": "and I will execute judgments upon Moab; and they shall know that I am HaShem.", "acv": "And I will execute judgments upon Moab, and they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "and on Moab will I execute judgments, and they shall know that I am Jehovah.", "webster": "And I will execute judgments upon Moab; and they shall know that I [am] the LORD.", "vulgate": "et in Moab faciam iudicia et scient quia ego Dominus;", "brenton": "And I will execute vengeance on Moab; and they shall know that I am the Lord."}}, {"v": 12, "ref": "25:12", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֣עַן עֲשׂ֥וֹת אֱד֛וֹם בִּ/נְקֹ֥ם נָקָ֖ם לְ/בֵ֣ית יְהוּדָ֑ה וַ/יֶּאְשְׁמ֥וּ אָשׁ֖וֹם וְ/נִקְּמ֥וּ בָ/הֶֽם", "en": {"kjv": "Thus saith the Lord God; Because that Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them;", "web": "Thus says the Lord Yahweh: Because Edom has dealt against the house of Judah by taking vengeance, and has greatly offended, and revenged himself on them;", "bsb": "This is what the Lord GOD says: ‘Because Edom acted vengefully against the house of Judah, and in so doing incurred grievous guilt,", "asv": "Thus saith the Lord Jehovah: Because that Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them;", "ylt": "Thus said the Lord Jehovah: Because of the doings of Edom, In taking vengeance on the house of Judah, Yea, they are very guilty, And they have taken vengeance on them.", "dra": "Thus saith the Lord God: Because Edom hath taken vengeance to revenge herself of the children of Juda, and hath greatly offended, and hath sought revenge of them:", "bbe": "This is what the Lord has said: Because Edom has taken his payment from the people of Judah, and has done great wrong in taking payment from them;", "geneva": "Thus sayth the Lord God, Because that Edom hath done euill by taking vengeance vpon the house of Iudah, and hath committed great offence, and reuenged himselfe vpon them,", "wycliffe": "The Lord God seith these thingis, For that that Ydumee dide veniaunce, that it avengide it silf of the sones of Juda, and synnede doynge trespas, and axide greetli veniaunce of hem;", "rotherham": "Thus, saith My Lord. Yahweh, Because of what Edom hath done, in taking vengeance on the house of Judah, so that they have become guilty again and again and have taken vengeance upon them,", "darby": "Thus saith the Lord Jehovah: Because Edom hath dealt against the house of Judah by taking vengeance, and hath made himself very guilty, and revenged himself upon them,", "twenty": "", "jps": "Thus saith the L-rd GOD: Because that Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them;", "acv": "Thus says the lord Jehovah: Because Edom has dealt against the house of Judah by taking vengeance, and has greatly offended, and revenged himself upon them,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them,", "webster": "Thus saith the Lord GOD; Because Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them;", "vulgate": "haec dicit Dominus Deus pro eo quod fecit Idumea ultionem ut se vindicaret de filiis Iuda peccavitque delinquens et vindictam expetivit de eis;", "brenton": "Thus saith the Lord; Because of what the Idumeans have done in taking vengeance on the house of Juda, and because they have remembered injuries, and have exacted full recompense;"}}, {"v": 13, "ref": "25:13", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה וְ/נָטִ֤תִי יָדִ/י֙ עַל אֱד֔וֹם וְ/הִכְרַתִּ֥י מִמֶּ֖/נָּה אָדָ֣ם וּ/בְהֵמָ֑ה וּ/נְתַתִּ֤י/הָ חָרְבָּה֙ מִ/תֵּימָ֔ן וּ/דְדָ֖נֶ/ה בַּ/חֶ֥רֶב יִפֹּֽלוּ", "en": {"kjv": "Therefore thus saith the Lord God; I will also stretch out mine hand upon Edom, and will cut off man and beast from it; and I will make it desolate from Teman; and they of Dedan shall fall by the sword.", "web": "therefore thus says the Lord Yahweh, I will stretch out my hand on Edom, and will cut off man and animal from it; and I will make it desolate from Teman; even to Dedan shall they fall by the sword.", "bsb": "therefore this is what the Lord GOD says: I will stretch out My hand against Edom and cut off from it both man and beast. I will make it a wasteland, and from Teman to Dedan they will fall by the sword.", "asv": "therefore thus saith the Lord Jehovah, I will stretch out my hand upon Edom, and will cut off man and beast from it; and I will make it desolate from Teman; even unto Dedan shall they fall by the sword.", "ylt": "Therefore, thus said the Lord Jehovah: I have stretched out My hand against Edom, And I have cut off from it man and beast, And given it up--a waste, from Teman even to Dedan, By sword they do fall.", "dra": "Therefore thus saith the Lord God: I will stretch forth my hand upon Edom, and will take away out of it man and beast, and will make it desolate from the south: and they that are in Dedan shall fall by the sword.", "bbe": "The Lord has said, My hand will be stretched out against Edom, cutting off from it man and beast: and I will make it waste, from Teman even as far as Dedan they will be put to the sword.", "geneva": "Therefore thus saith the Lord God, I will also stretch out mine hand vpon Edom, and destroy man and beast out of it, and I will make it desolate from Teman, and they of Dedan shall fall by the sworde.", "wycliffe": "therfor the Lord God seith these thingis, Y schal stretche forth myn hond on Idumee, and Y schal take awei fro it man and beeste, and Y schal make it desert of the south; and thei that ben in Dedan schulen falle bi swerd.", "rotherham": "Therefore, Thus, saith My Lord Yahweh, I will therefore stretch forth my hand over Edom, and will cut off therefrom man and beast, And will deliver it up as a desolation, from Teman, And they of Dedan, by the sword, shall fall,", "darby": "therefore thus saith the Lord Jehovah: I will also stretch out my hand upon Edom; and will cut off man and beast from it; and I will make it desolate from Teman; and unto Dedan shall they fall by the sword.", "twenty": "", "jps": "therefore thus saith the L-rd GOD: I will stretch out My hand upon Edom, and will cut off man and beast from it; and I will make it desolate from Teman, even unto Dedan shall they fall by the sword.", "acv": "therefore thus says the lord Jehovah: I will stretch out my hand upon Edom, and will cut off man and beast from it, and I will make it desolate. From Teman, even to Dedan they shall fall by the sword.", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: I will stretch out my hand upon Edom, and will cut off from it man and beast; and I will make it desolate from Teman; and unto Dedan shall they fall by the sword.", "webster": "Therefore thus saith the Lord GOD; I will also stretch out my hand upon Edom, and will cut off man and beast from it; and I will make it desolate from Teman; and they of Dedan shall fall by the sword.", "vulgate": "idcirco haec dicit Dominus Deus extendam manum meam super Idumeam et auferam de ea hominem et iumentum et faciam eam desertum ab austro et qui sunt in Daedan gladio cadent;", "brenton": "therefore thus saith the Lord; I will also stretch out my hand upon Idumea, and will utterly destroy out of it man and beast; and will make it desolate; and they that are pursued out of Thaeman shall fall by the sword."}}, {"v": 14, "ref": "25:14", "o": "וְ/נָתַתִּ֨י אֶת נִקְמָתִ֜/י בֶּ/אֱד֗וֹם בְּ/יַד֙ עַמִּ֣/י יִשְׂרָאֵ֔ל וְ/עָשׂ֣וּ בֶ/אֱד֔וֹם כְּ/אַפִּ֖/י וְ/כַ/חֲמָתִ֑/י וְ/יָֽדְעוּ֙ אֶת נִקְמָתִ֔/י נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And I will lay my vengeance upon Edom by the hand of my people Israel: and they shall do in Edom according to mine anger and according to my fury; and they shall know my vengeance, saith the Lord God.", "web": "I will lay my vengeance on Edom by the hand of my people Israel; and they shall do in Edom according to my anger and according to my wrath; and they shall know my vengeance, says the Lord Yahweh.", "bsb": "I will take My vengeance on Edom by the hand of My people Israel, and they will deal with Edom according to My anger and wrath. Then they will know My vengeance, declares the Lord GOD.’", "asv": "And I will lay my vengeance upon Edom by the hand of my people Israel; and they shall do in Edom according to mine anger and according to my wrath; and they shall know my vengeance, saith the Lord Jehovah.", "ylt": "And I have given My vengeance on Edom, By the hand of My people Israel, And they have done in Edom, According to My anger, and according to My fury, And they have known My vengeance, An affirmation of the Lord Jehovah.", "dra": "And I will lay my vengeance upon Edom by the hand of my people Israel: and they shall do in Edom according to my wrath, and my fury: and they shall know my vengeance, saith the Lord God.", "bbe": "I will take payment from Edom because of my people Israel; and I will take Edom in hand in my wrath and in my passion: and they will have experience of my reward, says the Lord.", "geneva": "And I will execute my vengeance vpon Edom by the hand of my people Israel, and they shall doe in Edom according to mine anger, and according to mine indignation, and they shall know my vengeance, sayth the Lord God.", "wycliffe": "And Y schal yyue my veniaunce on Idumee, bi the hond of my puple Israel; and thei schulen do in Edom bi my wraththe, and bi my strong veniaunce; and thei schulen knowe my veniaunce, seith the Lord God.", "rotherham": "And I will put forth mine avenging against Edom, by the hand of my people Israel, And they shall deal with Edom, according to mine anger and according to mine indignation,- So shall they know mine avenging, Declareth My Lord. Yahweh,", "darby": "And I will execute my vengeance upon Edom, by the hand of my people Israel; and they shall do in Edom according to mine anger and according to my fury; and they shall know my vengeance, saith the Lord Jehovah.", "twenty": "", "jps": "And I will lay My vengeance upon Edom by the hand of My people Israel; and they shall do in Edom according to Mine anger and according to My fury; and they shall know my vengeance, saith the L-rd GOD.", "acv": "And I will lay my vengeance upon Edom by the hand of my people Israel, and they shall do in Edom according to my anger and according to my wrath. And they shall know my vengeance, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will lay my vengeance upon Edom by the hand of my people Israel; and they shall deal with Edom according to mine anger, and according to my fury; and they shall know my vengeance, saith the Lord Jehovah.", "webster": "And I will lay my vengeance upon Edom by the hand of my people Israel: and they shall do in Edom according to my anger and according to my fury; and they shall know my vengeance, saith the Lord GOD.", "vulgate": "et dabo ultionem meam super Idumeam per manum populi mei Israhel et facient in Edom iuxta iram meam et furorem meum et scient vindictam meam dicit Dominus Deus;", "brenton": "And I will execute my vengeance on Idumea by the hand of my people Israel: and they shall deal in Idumea according to mine anger and according to my wrath, and they shall know my vengeance, saith the Lord."}}, {"v": 15, "ref": "25:15", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֛עַן עֲשׂ֥וֹת פְּלִשְׁתִּ֖ים בִּ/נְקָמָ֑ה וַ/יִּנָּקְמ֤וּ נָקָם֙ בִּ/שְׁאָ֣ט בְּ/נֶ֔פֶשׁ לְ/מַשְׁחִ֖ית אֵיבַ֥ת עוֹלָֽם", "en": {"kjv": "Thus saith the Lord God; Because the Philistines have dealt by revenge, and have taken vengeance with a despiteful heart, to destroy it for the old hatred;", "web": "Thus says the Lord Yahweh: Because the Philistines have dealt by revenge, and have taken vengeance with despite of soul to destroy with perpetual hostility;", "bsb": "This is what the Lord GOD says: ‘Because the Philistines acted in vengeance, taking vengeance with malice of soul to destroy Judah with ancient hostility,", "asv": "Thus saith the Lord Jehovah: Because the Philistines have dealt by revenge, and have taken vengeance with despite of soul to destroy with perpetual enmity;", "ylt": "Thus said the Lord Jehovah: Because of the doings of the Philistines in vengeance, And they take vengeance with despite in soul, To destroy--the enmity age-during!", "dra": "Thus saith the Lord God: Because the Philistines have taken vengeance, and have revenged themselves with all their mind, destroying and satisfying old enmities:", "bbe": "This is what the Lord has said: Because the Philistines have taken payment, with the purpose of causing shame and destruction with unending hate;", "geneva": "Thus sayth the Lord God, Because the Philistims haue executed vengeance, and reuenged themselues with a despitefull heart, to destroy it for the olde hatred,", "wycliffe": "The Lord God seith these thingis, For that that Palestyns diden veniaunce, and auengiden hem silf, with al wille sleynge, and fillynge elde enemytees;", "rotherham": "Thus saith My Lord Yahweh, Because of what the Philistines have done by way of vengeance,- In that they have taken vengeance with contempt in the soul, to destroy, with the enmity of age-past times.", "darby": "Thus saith the Lord Jehovah: Because the Philistines have dealt by revenge, and have taken vengeance with despite of soul, to destroy, from old hatred;", "twenty": "", "jps": "Thus saith the L-rd GOD: Because the Philistines have dealt by revenge, and have taken vengeance with disdain of soul to destroy, for the old hatred;", "acv": "Thus says the lord Jehovah: Because the Philistines have dealt by revenge, and have taken vengeance with spite of soul to destroy with perpetual enmity,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because the Philistines have dealt with revenge, and have taken vengeance, with a despiteful heart, even to destruction, from the old hatred;", "webster": "Thus saith the Lord GOD; Because the Philistines have dealt by revenge, and have taken vengeance with a despiteful heart, to destroy [it] for the old hatred;", "vulgate": "haec dicit Dominus Deus pro eo quod fecerunt Palestini in vindictam et ulti se sunt toto animo interficientes et implentes inimicitias veteres;", "brenton": "Therefore thus saith the Lord, Because the Philistines have wrought revengefully, and raised up vengeance rejoicing from their heart to destroy the Israelites to a man;"}}, {"v": 16, "ref": "25:16", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֨י נוֹטֶ֤ה יָדִ/י֙ עַל פְּלִשְׁתִּ֔ים וְ/הִכְרַתִּ֖י אֶת כְּרֵתִ֑ים וְ/הַ֣אֲבַדְתִּ֔י אֶת שְׁאֵרִ֖ית ח֥וֹף הַ/יָּֽם", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I will stretch out mine hand upon the Philistines, and I will cut off the Cherethims, and destroy the remnant of the sea coast.", "web": "therefore thus says the Lord Yahweh, Behold, I will stretch out my hand on the Philistines, and I will cut off the Cherethites, and destroy the remnant of the sea coast.", "bsb": "therefore this is what the Lord GOD says: Behold, I will stretch out My hand against the Philistines, and I will cut off the Cherethites and destroy the remnant along the coast.", "asv": "therefore thus saith the Lord Jehovah, Behold, I will stretch out my hand upon the Philistines, and I will cut off the Cherethites, and destroy the remnant of the sea coast.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am stretching out My hand against the Philistines, And I have cut off the Cherethim, And destroyed the remnant of the haven of the sea,", "dra": "Therefore thus saith the Lord God: Behold I will stretch forth my hand upon the Philistines, and will kill the killers, and will destroy the remnant of the sea coast.", "bbe": "The Lord has said, See, my hand will be stretched out against the Philistines, cutting off the Cherethites and sending destruction on the rest of the sea-land.", "geneva": "Therefore thus sayth the Lord God, Behold, I will stretche out mine hand vpon the Philistims, and I will cut off the Cherethims, and destroy the remnant of the sea coast.", "wycliffe": "therfor the Lord God seith these thingis, Lo! Y schal stretche forth myn hond on Palestyns, and Y schal sle sleeris, and Y schal leese the remenauntis of the se coost;", "rotherham": "Therefore, Thus, saith My Lord. Yahweh, Behold me! stretching forth my hand over the Philistines, And I will cut off the Cherethim,— And will cause to perish the remnant of the coast of the sea;", "darby": "therefore thus saith the Lord Jehovah: Behold, I stretch out my hands upon the Philistines, and I will cut off the Kerethites, and cause the remnant of the sea-coast to perish.", "twenty": "", "jps": "therefore thus saith the L-rd GOD: Behold, I will stretch out My hand upon the Philistines, and I will cut off the Cherethites, and destroy the remnant of the sea-coast.", "acv": "therefore thus says the lord Jehovah: Behold, I will stretch out my hand upon the Philistines, and I will cut off the Cherethites, and destroy the remnant of the sea coast.", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: Behold, I will stretch out my hand upon the Philistines, and I will cut off the Cherethites, and destroy the remnant upon the sea-coasts.", "webster": "Therefore thus saith the Lord GOD; Behold, I will stretch out my hand upon the Philistines, and I will cut off the Cherethims, and destroy the remnant of the sea coast.", "vulgate": "propterea haec dicit Dominus Deus ecce ego extendam manum meam super Palestinos et interficiam interfectores et perdam reliquias maritimae regionis;", "brenton": "therefore thus saith the Lord; Behold, I will stretch out my hand upon the Philistines, and will utterly destroy the Cretans, and will cut off the remnant that dwell by the sea-coast."}}, {"v": 17, "ref": "25:17", "o": "וְ/עָשִׂ֤יתִי בָ/ם֙ נְקָמ֣וֹת גְּדֹל֔וֹת בְּ/תוֹכְח֖וֹת חֵמָ֑ה וְ/יָֽדְעוּ֙ כִּֽי אֲנִ֣י יְהוָ֔ה בְּ/תִתִּ֥/י אֶת נִקְמָתִ֖/י בָּֽ/ם", "en": {"kjv": "And I will execute great vengeance upon them with furious rebukes; and they shall know that I am the Lord, when I shall lay my vengeance upon them.", "web": "I will execute great vengeance on them with wrathful rebukes; and they shall know that I am Yahweh, when I shall lay my vengeance on them.", "bsb": "I will execute great vengeance against them with furious reproof. Then they will know that I am the LORD, when I lay My vengeance upon them.’”", "asv": "And I will execute great vengeance upon them with wrathful rebukes; and they shall know that I am Jehovah, when I shall lay my vengeance upon them.", "ylt": "And done upon them great vengeance with furious reproofs, And they have known that I am Jehovah, In My giving out My vengeance on them!", "dra": "And I will execute great vengeance upon them, rebuking them in fury: and they shall know that I am the Lord, when I shall lay my vengeance upon them.", "bbe": "And I will take great payment from them with acts of wrath; and they will be certain that I am the Lord when I send my punishment on them.", "geneva": "And I will execute great vengeance vpon them with rebukes of mine indignation, and they shall knowe that I am the Lord, when I shall lay my vengeance vpon them.", "wycliffe": "and Y schal make grete veniaunces in hem, and Y schal repreue in strong veniaunce; and thei schulen wite, that Y am the Lord, whanne Y schal yyue my veniaunce on hem.", "rotherham": "And I will execute upon them great vengeance, with rebukes of indignation: shall they know that I am Yahweh, when I put forth mine avenging against them.", "darby": "And I will execute great vengeance upon them with furious rebukes; and they shall know that I [am] Jehovah, when I shall lay my vengeance upon them.", "twenty": "", "jps": "And I will execute great vengeance upon them with furious rebukes; and they shall know that I am HaShem, when I shall lay My vengeance upon them.'", "acv": "And I will execute great vengeance upon them with wrathful rebukes. And they shall know that I am Jehovah when I shall lay my vengeance upon them.", "anderson": "", "haweis": "", "noyes": "And I will execute great vengeance upon them with furious rebukes; and they shall know that I am Jehovah when I lay my vengeance upon them.", "webster": "And I will execute great vengeance upon them with furious rebukes; and they shall know that I [am] the LORD, when I shall lay my vengeance upon them.", "vulgate": "faciamque in eis ultiones magnas arguens in furore et scient quia ego Dominus cum dedero vindictam meam super eos;", "brenton": "And I will execute great vengeance upon them; and they shall know that I am the Lord, when I have brought my vengeance upon them."}}]}, {"c": 26, "verses": [{"v": 1, "ref": "26:1", "o": "וַ/יְהִ֛י בְּ/עַשְׁתֵּֽי עֶשְׂרֵ֥ה שָׁנָ֖ה בְּ/אֶחָ֣ד לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass in the eleventh year, in the first day of the month, that the word of the Lord came unto me, saying,", "web": "In the eleventh year, in the first of the month, Yahweh’s word came to me, saying,", "bsb": "In the eleventh month of the twelfth year, on the first day of the month, the word of the LORD came to me, saying,", "asv": "And it came to pass in the eleventh year, in the firstdayof the month, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the eleventh year, in the first of the month, there hath been a word of Jehovah unto me, saying: `Son of man,", "dra": "And it came to pass in the eleventh year, the first day of the month, that the word of the Lord came to me, saying:", "bbe": "Now in the eleventh year, on the first day of the month, the word of the Lord came to me, saying,", "geneva": "And in the eleuenth yeere, in the first day of the moneth, the worde of the Lord came vnto me, saying,", "wycliffe": "And it was doon in the enleuenthe yeer, in the firste dai of the monethe, the word of the Lord was maad to me, and he seide,", "rotherham": "And it came to pass in the eleventh year, on the first of the month, that the word of Yahweh came unto me, saying:", "darby": "And it came to pass in the eleventh year, on the first of the month, [that] the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass in the eleventh year, in the first day of the month, that the word of HaShem came unto me, saying:", "acv": "And it came to pass in the eleventh year, in the first day of the month, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And it came to pass in the eleventh year, on the first day of the month, that the word bf Jehovah came to me, saying:", "webster": "And it came to pass in the eleventh year, in the first [day] of the month, [that] the word of the LORD came to me, saying,", "vulgate": "et factum est in undecimo anno prima mensis factus est sermo Domini ad me dicens;", "brenton": "And it came to pass in the eleventh year, on the first day of the month, that the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "26:2", "o": "בֶּן אָדָ֗ם יַ֠עַן אֲשֶׁר אָ֨מְרָה צֹּ֤ר עַל יְרוּשָׁלִַ֨ם֙ הֶאָ֔ח נִשְׁבְּרָ֛ה דַּלְת֥וֹת הָ/עַמִּ֖ים נָסֵ֣בָּה אֵלָ֑/י אִמָּלְאָ֖ה הָחֳרָֽבָה", "en": {"kjv": "Son of man, because that Tyrus hath said against Jerusalem, Aha, she is broken that was the gates of the people: she is turned unto me: I shall be replenished, now she is laid waste:", "web": "Son of man, because Tyre has said against Jerusalem, Aha, she is broken: the gate of the peoples; she is turned to me; I shall be replenished, now that she is laid waste:", "bsb": "“Son of man, because Tyre has said of Jerusalem, ‘Aha! The gate to the nations is broken; it has swung open to me; now that she lies in ruins I will be filled,’", "asv": "Son of man, because that Tyre hath said against Jerusalem, Aha, she is broken that was the gate of the peoples; she is turned unto me; I shall be replenished, now that she is laid waste:", "ylt": "Because that Tyre hath said of Jerusalem: Aha, she hath been broken, the doors of the peoples, She hath turned round unto me, I am filled--she hath been laid waste,", "dra": "Son of man, because Tyre hath said of Jerusalem: Aha, the gates of the people are broken, she is turned to me: I shall be filled, now she is laid waste.", "bbe": "Son of man, because Tyre has said against Jerusalem, Aha, she who was the doorway of the peoples is broken; she is turned over to them; she who was full is made waste;", "geneva": "Sonne of man, because that Tyrus hath said against Ierusalem, Aha, the gate of the people is broken: it is turned vnto me: for seeing she is desolate, I shall be replenished,", "wycliffe": "Thou, sone of man, for that that Tire seide of Jerusalem, Wel! the yatis of puplis ben brokun, it is turned to me; Y schal be fillid, it is forsakun;", "rotherham": "Son of man, Because Tyre hath said concerning Jerusalem. Aha! She is broken that was the doors of the peoples. She is turned unto me,— I shall be filled, She is laid waste,", "darby": "Son of man, because Tyre hath said against Jerusalem, Aha, she is broken, the gate of the peoples! she is turned unto me: I shall be replenished [now] she is laid waste;", "twenty": "", "jps": "'Son of man, because that Tyre hath said against Jerusalem: aha, she is broken that was the gate of the peoples; she is turned unto me; I shall be filled with her that is laid waste;", "acv": "Son of man, because Tyre has said against Jerusalem, Aha, she is broken, the gate of the peoples. She has turned around to me. I shall be replenished, now that she is laid waste,", "anderson": "", "haweis": "", "noyes": "Son of man, because Tyre hath said against Jerusalem, \"Aha! she is broken that was the gate of the nations; now is all transferred to me; I shall be full, now that she is desolate!\"", "webster": "Son of man, because that Tyre hath said against Jerusalem, Aha, she is broken [that was] the gates of the people: she is turned to me: I shall be replenished, [now] she is laid waste:", "vulgate": "fili hominis pro eo quod dixit Tyrus de Hierusalem euge confractae sunt portae populorum conversa est ad me implebor deserta est;", "brenton": "Son of man, because Sor has said against Jerusalem, Aha, she is crushed: the nations are destroyed: she is turned to me: she that was full is made desolate:"}}, {"v": 3, "ref": "26:3", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֥י עָלַ֖יִ/ךְ צֹ֑ר וְ/הַעֲלֵיתִ֤י עָלַ֨יִ/ךְ֙ גּוֹיִ֣ם רַבִּ֔ים כְּ/הַעֲל֥וֹת הַ/יָּ֖ם לְ/גַלָּֽי/ו", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I am against thee, O Tyrus, and will cause many nations to come up against thee, as the sea causeth his waves to come up.", "web": "therefore thus says the Lord Yahweh, Behold, I am against you, Tyre, and will cause many nations to come up against you, as the sea causes its waves to come up.", "bsb": "therefore this is what the Lord GOD says: ‘Behold, O Tyre, I am against you, and I will raise up many nations against you, as the sea brings up its waves.", "asv": "therefore thus saith the Lord Jehovah, Behold, I am against thee, O Tyre, and will cause many nations to come up against thee, as the sea causeth its waves to come up.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am against thee, O Tyre, And have caused to come up against thee many nations, As the sea causeth its billows to come up.", "dra": "Therefore thus saith the Lord God: Behold I come against thee, O Tyre, and I will cause many nations to come up to thee, as the waves of the sea rise up.", "bbe": "For this cause the Lord has said, See, I am against you, O Tyre, and will send up a number of nations against you as the sea sends up its waves.", "geneva": "Therefore thus sayth the Lord God, Beholde, I come against thee, O Tyrus, and I will bring vp many nations against thee, as the sea mounteth vp with his waues.", "wycliffe": "therfor the Lord God seith these thingis, Lo! Tire, Y on thee; and Y schal make many folkis to stie to thee, as the see flowynge stieth.", "rotherham": "Therefore, Thus, saith My Lord Yahweh, Behold me! against thee O Tyre,— So then I will bring up against thee many nations, As the sea bringeth up its rolling waves;", "darby": "therefore thus saith the Lord Jehovah: Behold, I am against thee, Tyre, and will cause many nations to come up against thee, as the sea causeth its waves to come up.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: behold, I am against thee, O Tyre, and will cause many nations to come up against thee, as the sea causeth its waves to come up.", "acv": "therefore thus says the lord Jehovah: Behold, I am against thee, O Tyre, and will cause many nations to come up against thee, as the sea causes its waves to come up.", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: Behold, I am against thee, O Tyre, and I will cause many nations to come up against thee, as the sea causeth his waves to come up.", "webster": "Therefore thus saith the Lord GOD; Behold, I [am] against thee, O Tyre, and will cause many nations to come up against thee, as the sea causeth its waves to come up.", "vulgate": "propterea haec dicit Dominus Deus ecce ego super te Tyre et ascendere faciam ad te gentes multas sicut ascendit mare fluctuans;", "brenton": "therefore thus saith the Lord; Behold, I am against thee, O Sor, and I will bring up many nations against thee, as the sea comes up with its waves."}}, {"v": 4, "ref": "26:4", "o": "וְ/שִׁחֲת֞וּ חֹמ֣וֹת צֹ֗ר וְ/הָֽרְסוּ֙ מִגְדָּלֶ֔י/הָ וְ/סִֽחֵיתִ֥י עֲפָרָ֖/הּ מִמֶּ֑/נָּה וְ/נָתַתִּ֥י אוֹתָ֖/הּ לִ/צְחִ֥יחַ סָֽלַע", "en": {"kjv": "And they shall destroy the walls of Tyrus, and break down her towers: I will also scrape her dust from her, and make her like the top of a rock.", "web": "They shall destroy the walls of Tyre, and break down her towers: I will also scrape her dust from her, and make her a bare rock.", "bsb": "They will destroy the walls of Tyre and demolish her towers. I will scrape the soil from her and make her a bare rock.", "asv": "And they shall destroy the walls of Tyre, and break down her towers: I will also scrape her dust from her, and make her a bare rock.", "ylt": "And they have destroyed the walls of Tyre, And they have broken down her towers, And I have scraped her dust from her, And made her for a clear place of a rock.", "dra": "And they shall break down the walls of Tyre, and destroy the towers thereof: and I will scrape her dust from her, and make her like a smooth rock.", "bbe": "And they will give the walls of Tyre to destruction and have its towers broken: and I will take even her dust away from her, and make her an uncovered rock", "geneva": "And they shall destroy the walles of Tyrus and breake downe her towres: I will also scrape her dust from her, and make her like the top of a rocke.", "wycliffe": "And thei schulen distrie the wallis of Tire, and thei schulen distrie the touris therof; and Y schal rase the dust therof fro it, and Y schal yyue it in to a `moost clere stoon.", "rotherham": "And they shall destroy the walls of Tyre. And break down her towers, And I will scrape clean her dust from off her, —And make of her the glaring face of a cliff:", "darby": "And they shall destroy the walls of Tyre, and break down her towers. And I will scrape her dust from her, and make her a bare rock.", "twenty": "", "jps": "And they shall destroy the walls of Tyre, and break down her towers; I will also scrape her dust from her, and make her a bare rock.", "acv": "And they shall destroy the walls of Tyre, and break down her towers. I will also scrape her dust from her, and make her a bare rock.", "anderson": "", "haweis": "", "noyes": "And they shall destroy the walls of Tyre, and break down her towers; and I will scrape off her earth from her, and make her like a naked rock.", "webster": "And they shall destroy the walls of Tyre, and break down her towers: I will also scrape her dust from her, and make her like the top of a rock.", "vulgate": "et dissipabunt muros Tyri et destruent turres eius et radam pulverem eius de ea et dabo eam in limpidissimam petram;", "brenton": "And they shall cast down the walls of Sor, and shall cast down thy towers: and I will scrape her dust from off her, and make her a bare rock."}}, {"v": 5, "ref": "26:5", "o": "מִשְׁטַ֨ח חֲרָמִ֤ים תִּֽהְיֶה֙ בְּ/ת֣וֹךְ הַ/יָּ֔ם כִּ֚י אֲנִ֣י דִבַּ֔רְתִּי נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה וְ/הָיְתָ֥ה לְ/בַ֖ז לַ/גּוֹיִֽם", "en": {"kjv": "It shall be a place for the spreading of nets in the midst of the sea: for I have spoken it, saith the Lord God: and it shall become a spoil to the nations.", "web": "She shall be a place for the spreading of nets in the midst of the sea; for I have spoken it, says the Lord Yahweh; and she shall become a plunder to the nations.", "bsb": "She will become a place to spread nets in the sea, for I have spoken, declares the Lord GOD. She will become plunder for the nations,", "asv": "She shall be a place for the spreading of nets in the midst of the sea; for I have spoken it, saith the Lord Jehovah; and she shall become a spoil to the nations.", "ylt": "A spreading place of nets she is in the midst of the sea, For I--I have spoken--an affirmation of the Lord Jehovah, And she hath been for a spoil to nations.", "dra": "She shall be a drying place for nets in the midst of the sea, because I have spoken it, saith the Lord God: and she shall be a spoil to the nations.", "bbe": "She will be a place for the stretching out of nets in the middle of the sea; for I have said it, says the Lord: and her goods will be given over to the nations.", "geneva": "Thou shalt be for the spreading of nettes in the middes of the sea: for I haue spoken it, sayth the Lord God, and it shalbe a spoile to ye nations.", "wycliffe": "Driyng of nettis schal be in the myddis of the see, for Y spak, seith the Lord God. And Tire schal be in to rauysching to hethene men.", "rotherham": "A place for the spreading of nets, shall she become, in the midst of the sea, For, I, have spoken Declareth My Lord. Yahweh,-And she shall become a prey to the nations.", "darby": "She shall be [a place] for the spreading of nets in the midst of the sea; for I have spoken [it], saith the Lord Jehovah; and she shall become a spoil for the nations.", "twenty": "", "jps": "She shall be a place for the spreading of nets in the midst of the sea; for I have spoken it, saith the L-rd GOD; and she shall become a spoil to the nations.", "acv": "She shall be a place for the spreading of nets in the midst of the sea, for I have spoken it, says the lord Jehovah. And she shall become a spoil to the nations,", "anderson": "", "haweis": "", "noyes": "She shall be a place for the spreading of nets in the midst of the sea; for I have spoken it, saith the Lord Jehovah. And she shall be to the nations for a spoil;", "webster": "It shall be [a place for] the spreading of nets in the midst of the sea: for I have spoken [it], saith the Lord GOD: and it shall become a spoil to the nations.", "vulgate": "siccatio sagenarum erit in medio maris quia ego locutus sum ait Dominus Deus et erit in direptionem gentibus;", "brenton": "She shall be in the midst of the sea a place for repairing nets: for I have spoken it, saith the Lord: and it shall be a spoil for the nations."}}, {"v": 6, "ref": "26:6", "o": "וּ/בְנוֹתֶ֨י/הָ֙ אֲשֶׁ֣ר בַּ/שָּׂדֶ֔ה בַּ/חֶ֖רֶב תֵּהָרַ֑גְנָה וְ/יָדְע֖וּ כִּי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And her daughters which are in the field shall be slain by the sword; and they shall know that I am the Lord.", "web": "Her daughters who are in the field shall be slain with the sword: and they shall know that I am Yahweh.", "bsb": "and the villages on her mainland will be slain by the sword. Then they will know that I am the LORD.’", "asv": "And her daughters that are in the field shall be slain with the sword: and they shall know that I am Jehovah.", "ylt": "And her daughters who are in the field, by sword they are slain, And they have known that I am Jehovah,", "dra": "Her daughters also that are in the field, shall be slain by the sword: and they shall know that I am the Lord.", "bbe": "And her daughters in the open country will be put to the sword: and they will be certain that I am the Lord.", "geneva": "And her daughters which are in the fielde, shall be slaine by the sworde, and they shall know that I am the Lord.", "wycliffe": "And the douytris therof that ben in the feeld, schulen be slayn bi swerd; and thei schulen wite, that Y am the Lord.", "rotherham": "And her daughters that are in the field: with the sword shall be slain: So shall they know that I am Yahweh.", "darby": "And her daughters that are in the field shall be slain by the sword; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "And her daughters that are in the field shall be slain with the sword; and they shall know that I am HaShem.", "acv": "and her daughters who are in the field shall be slain with the sword. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "and her daughters that are upon the land shall be slain by the sword; and they shall know that I am Jehovah.", "webster": "And her daughters who [are] in the field shall be slain by the sword; and they shall know that I [am] the LORD.", "vulgate": "filiae quoque eius quae sunt in agro gladio interficientur et scient quia ego Dominus;", "brenton": "And her daughters which are in the field shall be slain with the sword, and they shall know that I am the Lord."}}, {"v": 7, "ref": "26:7", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֧י מֵבִ֣יא אֶל צֹ֗ר נְבוּכַדְרֶאצַּ֧ר מֶֽלֶךְ בָּבֶ֛ל מִ/צָּפ֖וֹן מֶ֣לֶךְ מְלָכִ֑ים בְּ/ס֛וּס וּ/בְ/רֶ֥כֶב וּ/בְ/פָרָשִׁ֖ים וְ/קָהָ֥ל וְ/עַם רָֽב", "en": {"kjv": "For thus saith the Lord God; Behold, I will bring upon Tyrus Nebuchadrezzar king of Babylon, a king of kings, from the north, with horses, and with chariots, and with horsemen, and companies, and much people.", "web": "For thus says the Lord Yahweh: Behold, I will bring on Tyre Nebuchadnezzar king of Babylon, king of kings, from the north, with horses, and with chariots, and with horsemen, and a company, and many people.", "bsb": "For this is what the Lord GOD says: ‘Behold, I will bring against Tyre from the north Nebuchadnezzar king of Babylon, king of kings, with horses and chariots, with cavalry and a great company of troops.", "asv": "For thus saith the Lord Jehovah: Behold, I will bring upon Tyre Nebuchadrezzar king of Babylon, king of kings, from the north, with horses, and with chariots, and with horsemen, and a company, and much people.", "ylt": "For, thus said the Lord Jehovah: Lo, I am bringing in unto Tyre Nebuchadrezzar king of Babylon, From the north--a king of kings, With horse, and with chariot, and with horsemen, Even an assembly, and a numerous people.", "dra": "For thus saith the Lord God: Behold I will bring against Tyre Nabuchodonosor king of Babylon, the king of kings, from the north, with horses, and chariots, and horsemen, and companies, and much people.", "bbe": "For this is what the Lord has said: See, I will send up from the north Nebuchadrezzar, king of Babylon, king of kings, against Tyre, with horses and war-carriages and with an army and great numbers of people.", "geneva": "For thus sayth the Lord God, Behold, I will bring vpon Tyrus Nebuchad-nezzar King of Babel, a King of Kings from the North, with horses and with charets, and with horsemen, with a multitude and much people.", "wycliffe": "For whi the Lord God seith these thingis, Lo! Y schal brynge to Tire Nabugodonosor, the king of Babiloyne, fro the north, the kyng of kyngis, with horsis, and charis, and knyytis, and with a cumpeny, and greet puple.", "rotherham": "For thus saith My Lord. Yahweh, Behold me! bringing against Tyre. Nebuchadrezzar king of Babylon out of the North. a king of kings,—with horses and with chariots and with horsemen, and a gathered host, and much people.", "darby": "For thus saith the Lord Jehovah: Behold, I will bring from the north, against Tyre, Nebuchadrezzar king of Babylon, the king of kings, with horses, and with chariots, and with horsemen, and an assemblage, and much people.", "twenty": "", "jps": "For thus saith the L-rd GOD: Behold, I will bring upon Tyre Nebuchadrezzar king of Babylon, king of kings, from the north, with horses, and with chariots, and with horsemen, and a company, and much people.", "acv": "For thus says the lord Jehovah: Behold, I will bring upon Tyre, Nebuchadrezzar king of Babylon, king of kings, from the north, with horses, and with chariots, and with horsemen, and a company, and many people.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: Behold, I will bring against Tyre Nebuchadnezzar, the king of Babylon, a king of kings from the North, with horses, and with chariots, and with horsemen, and a vast multitude of people.", "webster": "For thus saith the Lord GOD; Behold, I will bring upon Tyre Nebuchadrezzar king of Babylon, a king of kings, from the north, with horses, and with chariots, and with horsemen, and companies, and much people.", "vulgate": "quia haec dicit Dominus Deus ecce ego adducam ad Tyrum Nabuchodonosor regem Babylonis ab aquilone regem regum cum equis et curribus et equitibus et coetu populoque magno;", "brenton": "For thus saith the Lord; Behold, I will bring up against thee, O Sor, Nabuchodonosor king of Babylon from the north: he is a king of kings, with horses, and chariots, and horsemen, and a concourse of very many nations."}}, {"v": 8, "ref": "26:8", "o": "בְּנוֹתַ֥יִ/ךְ בַּ/שָּׂדֶ֖ה בַּ/חֶ֣רֶב יַהֲרֹ֑ג וְ/נָתַ֨ן עָלַ֜יִ/ךְ דָּיֵ֗ק וְ/שָׁפַ֤ךְ עָלַ֨יִ/ךְ֙ סֹֽלְלָ֔ה וְ/הֵקִ֥ים עָלַ֖יִ/ךְ צִנָּֽה", "en": {"kjv": "He shall slay with the sword thy daughters in the field: and he shall make a fort against thee, and cast a mount against thee, and lift up the buckler against thee.", "web": "He shall kill your daughters in the field with the sword; and he shall make forts against you, and cast up a mound against you, and raise up the buckler against you.", "bsb": "He will slaughter the villages of your mainland with the sword; he will set up siege works against you, build a ramp to your walls, and raise his shields against you.", "asv": "He shall slay with the sword thy daughters in the field; and he shall make forts against thee, and cast up a mound against thee, and raise up the buckler against thee.", "ylt": "Thy daughters in the field by sword he slayeth, And he hath made against thee a fort, And hath poured out against thee a mount, And hath raised against thee a buckler.", "dra": "Thy daughters that are in the field, he shall kill with the sword: and he shall compass thee with forts, and shall cast up a mount round about: and he shall lift up the buckler against thee.", "bbe": "He will put to the sword your daughters in the open country: he will make strong walls against you and put up an earthwork against you, arming himself for war against you.", "geneva": "He shall slay with the sword thy daughters in the fielde, and he shall make a fort against thee, and cast a mount against thee, and lift vp the buckler against thee.", "wycliffe": "He schal sle bi swerd thi douytris that ben in the feeld, and he schal cumpasse thee with strengthingis, and he schal bere togidere erthe in cumpas. And he schal reise a scheeld ayens thee,", "rotherham": "Thy daughters in the field—with the sword, shall he slay,- And shall set against thee a siege-wall And cast up against thee an earthwork, And set up against thee a large shield;", "darby": "He shall slay with the sword thy daughters in the field, and he shall make forts against thee, and cast up a mound against thee, and lift up the target against thee;", "twenty": "", "jps": "He shall slay with the sword thy daughters in the field; and he shall make forts against thee, and cast up a mound against thee, and set up bucklers against thee.", "acv": "He shall kill thy daughters in the field with the sword. And he shall make forts against thee, and cast up a mound against thee, and raise up the buckler against thee.", "anderson": "", "haweis": "", "noyes": "Thy daughters upon the land shall he slay with the sword; and he shall set a tower against thee, and cast up a mound against thee, and lift up the buckler against thee;", "webster": "He shall slay with the sword thy daughters in the field: and he shall make a fort against thee, and cast a mount against thee, and lift up the buckler against thee.", "vulgate": "filias tuas quae sunt in agro gladio interficiet et circumdabit te munitionibus et conportabit aggerem in gyro et levabit contra te clypeum;", "brenton": "He shall slay thy daughters that are in the field with the sword, and shall set a watch against thee, and build forts around thee, and carry a rampart round against thee, and set up warlike works, and array his spears against thee."}}, {"v": 9, "ref": "26:9", "o": "וּ/מְחִ֣י קָֽבָלּ֔/וֹ יִתֵּ֖ן בְּ/חֹֽמוֹתָ֑יִ/ךְ וּ/מִ֨גְדְּלֹתַ֔יִ/ךְ יִתֹּ֖ץ בְּ/חַרְבוֹתָֽי/ו", "en": {"kjv": "And he shall set engines of war against thy walls, and with his axes he shall break down thy towers.", "web": "He shall set his battering engines against your walls, and with his axes he shall break down your towers.", "bsb": "He will direct the blows of his battering rams against your walls and tear down your towers with his axes.", "asv": "And he shall set his battering engines against thy walls, and with his axes he shall break down thy towers.", "ylt": "And a battering-ram before him he placeth against thy walls, And thy towers he breaketh by his weapons.", "dra": "And he shall set engines of war and battering rams against thy walls, and shall destroy thy towers with his arms.", "bbe": "He will put up his engines of war against your walls, and your towers will be broken down by his axes.", "geneva": "He shall set engins of warre before him against thy walles, and with his weapons breake downe thy towres.", "wycliffe": "and he schal tempre engynes lijc vineres, and engines `that ben clepid wetheris ayens thi wallis; and he schal distrie thi touris bi his armure.", "rotherham": "And the stroke of his attacking-engine, will he direct against thy walls,— And thy towers, will he break down with his axes.", "darby": "and he shall set his engines of attack against thy walls, and with his spikes he shall break down thy towers.", "twenty": "", "jps": "And he shall set his battering engines against thy walls, and with his axes he shall break down thy towers.", "acv": "And he shall set his battering engines against thy walls, and with his axes he shall break down thy towers.", "anderson": "", "haweis": "", "noyes": "and his battering-rams shall be set against thy walls, and thy towers shall he break down with axes.", "webster": "And he shall set engines of war against thy walls, and with his axes he shall break down thy towers.", "vulgate": "et vineas et arietes temperabit in muros tuos et turres tuas destruet in armatura sua;", "brenton": "He shall cast down with his swords thy walls and thy towers."}}, {"v": 10, "ref": "26:10", "o": "מִ/שִּׁפְעַ֥ת סוּסָ֖י/ו יְכַסֵּ֣/ךְ אֲבָקָ֑/ם מִ/קּוֹל֩ פָּרַ֨שׁ וְ/גַלְגַּ֜ל וָ/רֶ֗כֶב תִּרְעַ֨שְׁנָה֙ חֽוֹמוֹתַ֔יִ/ךְ בְּ/בֹא/וֹ֙ בִּ/שְׁעָרַ֔יִ/ךְ כִּ/מְבוֹאֵ֖י עִ֥יר מְבֻקָּעָֽה", "en": {"kjv": "By reason of the abundance of his horses their dust shall cover thee: thy walls shall shake at the noise of the horsemen, and of the wheels, and of the chariots, when he shall enter into thy gates, as men enter into a city wherein is made a breach.", "web": "By reason of the abundance of his horses their dust shall cover you: your walls shall shake at the noise of the horsemen, and of the wagons, and of the chariots, when he shall enter into your gates, as men enter into a city in which is made a breach.", "bsb": "His multitude of horses will cover you in their dust. When he enters your gates as an army entering a breached city, your walls will shake from the noise of cavalry, wagons, and chariots.", "asv": "By reason of the abundance of his horses their dust shall cover thee: thy walls shall shake at the noise of the horsemen, and of the wagons, and of the chariots, when he shall enter into thy gates, as men enter into a city wherein is made a breach.", "ylt": "From the abundance of his horses cover thee doth their dust, From the noise of horseman, and wheel, and rider, Shake do thy walls, in his coming in to thy gates, As the coming into a city broken-up.", "dra": "By reason of the multitude of his horses, their dust shall cover thee: thy walls shall shake at the noise of the horsemen, and wheels, and chariots, when they shall go in at thy gates, as by the entrance of a city that is destroyed.", "bbe": "Because of the number of his horses you will be covered with their dust: your walls will be shaking at the noise of the horsemen and of the wheels and of the war-carriages, when he comes through your doorways, as into a town which has been broken open.", "geneva": "The dust of his horses shall couer thee, for their multitude: thy walles shall shake at the noise of the horsemen, and of the wheeles, and of the charets, when he shall enter into thy gates as into the entrie of a citie that is broken downe.", "wycliffe": "Bi flowynge of his horsis, the dust of tho schal hile thee; thi wallis schulen be mouyd of the soun of knyytis, and of wheelis, and of charis; whanne he schal entre bi the yatis, as bi entryngis of a citee distried,", "rotherham": "By reason of the multitude of his horses, their dust shall cover thee,— At the noise of horseman and wheel and chariot, shall thy walls tremble, when he entereth into thy gates Just as they do who enter a city broken open.", "darby": "By reason of the abundance of his horses their dust shall cover thee; thy walls shall shake at the noise of the horsemen, and of the wheels, and of the chariots, when he shall enter through thy gates, as a city is entered into, wherein is made a breach.", "twenty": "", "jps": "By reason of the abundance of his horses their dust shall cover thee; at the noise of the horsemen, and of the wheels, and of the chariots, thy walls shall shake, when he shall enter into thy gates, as men enter into a city wherein is made a breach.", "acv": "Because of the abundance of his horses their dust shall cover thee. Thy walls shall shake at the noise of the horsemen, and of the wagons, and of the chariots, when he shall enter into thy gates, as men enter into a city in which a breach is made.", "anderson": "", "haweis": "", "noyes": "By reason of the great number of his horses, their dust shall cover thee; thy walls shall shake at the noise of the horsemen, and of the wheels, and of the chariots, when he entereth into thy gates, as men enter into a city that is broken through.", "webster": "By reason of the abundance of his horses their dust shall cover thee: thy walls shall shake at the noise of the horsemen, and of the wheels, and of the chariots, when he shall enter into thy gates, as men enter into a city in which is made a breach.", "vulgate": "inundatione equorum eius operiet te pulvis eorum a sonitu equitum et rotarum et curruum movebuntur muri tui dum ingressus fuerit portas tuas quasi per introitus urbis dissipatae;", "brenton": "By reason of thy multitude of his horses their dust shall cover thee, and by reason of the sound of his horsemen and the wheels of his chariots the walls shall be shaken, when he enters into thy gates, as one entering into a city from the plain."}}, {"v": 11, "ref": "26:11", "o": "בְּ/פַרְס֣וֹת סוּסָ֔י/ו יִרְמֹ֖ס אֶת כָּל חֽוּצוֹתָ֑יִ/ךְ עַמֵּ/ךְ֙ בַּ/חֶ֣רֶב יַהֲרֹ֔ג וּ/מַצְּב֥וֹת עֻזֵּ֖/ךְ לָ/אָ֥רֶץ תֵּרֵֽד", "en": {"kjv": "With the hoofs of his horses shall he tread down all thy streets: he shall slay thy people by the sword, and thy strong garrisons shall go down to the ground.", "web": "With the hoofs of his horses shall he tread down all your streets; he shall kill your people with the sword; and the pillars of your strength shall go down to the ground.", "bsb": "The hooves of his horses will trample all your streets. He will slaughter your people with the sword, and your mighty pillars will fall to the ground.", "asv": "With the hoofs of his horses shall he tread down all thy streets; he shall slay thy people with the sword; and the pillars of thy strength shall go down to the ground.", "ylt": "With hoofs of his horses he treadeth all thine out-places, Thy people by sword he doth slay, And the pillars of thy strength to the earth come down.", "dra": "With the hoofs of his horses he shall tread down all thy streets, thy people he shall kill with the sword, and thy famous statues shall fall to the ground.", "bbe": "Your streets will be stamped down by the feet of his horses: he will put your people to the sword, and will send down the pillars of your strength to the earth.", "geneva": "With the hooues of his horses shall he treade downe all thy streetes: he shall slay thy people by the sworde, and the pillars of thy strength shall fall downe to the ground.", "wycliffe": "with the clees of hise horsis he schal defoule alle thi stretis. He shal sle bi swerd thi puple, and thi noble ymagis schulen falle doun in to erthe.", "rotherham": "With the hoofs of his horses, shall he tread down all thy streets,— Thy people-with the sword, shall he slay, And thy pillars of strength to the earth, shall go down.", "darby": "With the hoofs of his horses shall he tread down all thy streets; he shall slay thy people by the sword, and the pillars of thy strength shall go down to the ground.", "twenty": "", "jps": "With the hoofs of his horses shall he tread down all thy streets; he shall slay thy people with the sword, and the pillars of thy strength shall go down to the ground.", "acv": "With the hoofs of his horses he shall tread down all thy streets. He shall kill thy people with the sword, and the pillars of thy strength shall go down to the ground.", "anderson": "", "haweis": "", "noyes": "With the hoofs of his horses shall he tread down all thy streets; thy people he shall slay with the sword; and the idols of thy strength shall fall to the ground.", "webster": "With the hoofs of his horses shall he tread down all thy streets: he shall slay thy people by the sword, and thy strong garrisons shall go down to the ground.", "vulgate": "ungulis equorum suorum conculcabit omnes plateas tuas populum tuum gladio caedet et statuae tuae nobiles in terram corruent;", "brenton": "With the hoofs of his horses they shall trample all thy streets: he shall slay thy people with the sword, and shall bring down to the ground the support of thy strength."}}, {"v": 12, "ref": "26:12", "o": "וְ/שָׁלְל֣וּ חֵילֵ֗/ךְ וּ/בָֽזְזוּ֙ רְכֻלָּתֵ֔/ךְ וְ/הָֽרְסוּ֙ חוֹמוֹתַ֔יִ/ךְ וּ/בָתֵּ֥י חֶמְדָּתֵ֖/ךְ יִתֹּ֑צוּ וַ/אֲבָנַ֤יִ/ךְ וְ/עֵצַ֨יִ/ךְ֙ וַֽ/עֲפָרֵ֔/ךְ בְּ/ת֥וֹךְ מַ֖יִם יָשִֽׂימוּ", "en": {"kjv": "And they shall make a spoil of thy riches, and make a prey of thy merchandise: and they shall break down thy walls, and destroy thy pleasant houses: and they shall lay thy stones and thy timber and thy dust in the midst of the water.", "web": "They shall make a plunder of your riches, and make a prey of your merchandise; and they shall break down your walls, and destroy your pleasant houses; and they shall lay your stones and your timber and your dust in the midst of the waters.", "bsb": "They will plunder your wealth and pillage your merchandise. They will demolish your walls, tear down your beautiful homes, and throw your stones and timber and soil into the water.", "asv": "And they shall make a spoil of thy riches, and make a prey of thy merchandise; and they shall break down thy walls, and destroy thy pleasant houses; and they shall lay thy stones and thy timber and thy dust in the midst of the waters.", "ylt": "And they have spoiled thy wealth, And they have plundered thy merchandise, And they have thrown down thy walls, And thy desirable houses they break down, And thy stones, and thy wood, and thy dust, In the midst of the waters they place.", "dra": "They shall waste thy riches, they shall make a spoil of thy merchandise: and they shall destroy thy walls, and pull down thy fine houses: and they shall lay thy stones and thy timber, and thy dust in the midst of the waters.", "bbe": "They will take by force all your wealth and go off with the goods with which you do trade: they will have your walls broken down and all the houses of your desire given up to destruction: they will put your stones and your wood and your dust deep in the water.", "geneva": "And they shall robbe thy riches, and spoyle thy marchandise, and they shall breake downe thy walles, and destroy thy pleasant houses, and they shall cast thy stones and thy timber and thy dust into the middes of the water.", "wycliffe": "Thei schulen waste thi richessis, thei schulen rauysche thi marchaundies; and thei schulen distrie thi wallis, and thei schulen distrie thin housis ful clere, and thi stoonys, and thi trees, and thei schulen putte thi dust in the myddis of watris.", "rotherham": "And they shall spoil thy wealth And make a prey of thy merchandise, And break down thy walls And thy pleasant houses, shall they lay in ruins; And thy stones and thy timber and thy dust—in the midst of the waters, shall they lay.", "darby": "And they shall make a spoil of thy riches, and make a prey of thy wares; and they shall break down thy walls, and destroy thy pleasant houses; and they shall lay thy stones and thy timber and thy dust in the midst of the waters.", "twenty": "", "jps": "And they shall make a spoil of thy riches, and make a prey of thy merchandise; and they shall break down thy walls, and destroy the houses of thy delight; and thy stones and thy timber and thy dust shall they lay in the midst of the waters.", "acv": "And they shall make a spoil of thy riches, and make a prey of thy merchandise. And they shall break down thy walls, and destroy thy pleasant houses, and they shall lay thy stones and thy timber and thy dust in the midst of the waters.", "anderson": "", "haweis": "", "noyes": "And they shall make a spoil of thy riches, and make a prey of thy merchandise; and they shall break down thy walls, and destroy thy beautiful houses; and thy stones and thy timber and thine earth shall they lay in the midst of the waters.", "webster": "And they shall make a spoil of thy riches, and make a prey of thy merchandise: and they shall break down thy walls, and destroy thy pleasant houses: and they shall lay thy stones and thy timber and thy dust in the midst of the water.", "vulgate": "vastabunt opes tuas diripient negotiationes tuas et destruent muros tuos et domos tuas praeclaras subvertent et lapides tuos et ligna tua et pulverem tuum in medio aquarum ponent;", "brenton": "And he shall prey upon thy power, and plunder thy substance, and shall cast down thy walls, and break down thy pleasant houses: and he shall cast thy stones and thy timber and thy dust into the midst of thy sea."}}, {"v": 13, "ref": "26:13", "o": "וְ/הִשְׁבַּתִּ֖י הֲמ֣וֹן שִׁירָ֑יִ/ךְ וְ/ק֣וֹל כִּנּוֹרַ֔יִ/ךְ לֹ֥א יִשָּׁמַ֖ע עֽוֹד", "en": {"kjv": "And I will cause the noise of thy songs to cease; and the sound of thy harps shall be no more heard.", "web": "I will cause the noise of your songs to cease; and the sound of your harps shall be no more heard.", "bsb": "So I will silence the sound of your songs, and the music of your lyres will no longer be heard.", "asv": "And I will cause the noise of thy songs to cease; and the sound of thy harps shall be no more heard.", "ylt": "And I have caused the noise of thy songs to cease, And the voice of thy harps is heard no more.", "dra": "And I will make the multitude of thy songs to cease, and the sound of thy harps shall be heard no more.", "bbe": "I will put an end to the noise of your songs, and the sound of your instruments of music will be gone for ever.", "geneva": "Thus will I cause the sounde of thy songs to cease, and the sound of thine harpes shall be no more heard.", "wycliffe": "And Y schal make to reste the multitude of thi syngeris, and the sown of thin harpis schal no more be herd;", "rotherham": "And I will cause to cease the hum of thy songs; And the sound of thy lyres, shall not be heard any more.", "darby": "And I will cause the noise of thy songs to cease; and the sound of thy harps shall be no more heard.", "twenty": "", "jps": "And I will cause the noise of thy songs to cease, and the sound of thy harps shall be no more heard.", "acv": "And I will cause the noise of thy songs to cease, and the sound of thy harps shall no more be heard.", "anderson": "", "haweis": "", "noyes": "And I will cause the noise of thy songs to cease, and the sound of thy harps shall be no more heard.", "webster": "And I will cause the noise of thy songs to cease; and the sound of thy harps shall be no more heard.", "vulgate": "et quiescere faciam multitudinem canticorum tuorum et sonitus cithararum tuarum non audietur amplius;", "brenton": "And he shall destroy the multitude of thy musicians, and the sound of thy psalteries shall be heard no more."}}, {"v": 14, "ref": "26:14", "o": "וּ/נְתַתִּ֞י/ךְ לִ/צְחִ֣יחַ סֶ֗לַע מִשְׁטַ֤ח חֲרָמִים֙ תִּֽהְיֶ֔ה לֹ֥א תִבָּנֶ֖ה ע֑וֹד כִּ֣י אֲנִ֤י יְהוָה֙ דִּבַּ֔רְתִּי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And I will make thee like the top of a rock: thou shalt be a place to spread nets upon; thou shalt be built no more: for I the Lord have spoken it, saith the Lord God.", "web": "I will make you a bare rock; you shall be a place for the spreading of nets; you shall be built no more: for I Yahweh have spoken it, says the Lord Yahweh.", "bsb": "I will make you a bare rock, and you will become a place to spread the fishing nets. You will never be rebuilt, for I, the LORD, have spoken, declares the Lord GOD.’", "asv": "And I will make thee a bare rock; thou shalt be a place for the spreading of nets; thou shalt be built no more: for I Jehovah have spoken it, saith the Lord Jehovah.", "ylt": "And I have given thee up for a clear place of a rock, A spreading-place of nets thou art, Thou art not built up any more, For I, Jehovah, I have spoken, An affirmation of the Lord Jehovah.", "dra": "And I will make thee like a naked rock, thou shalt be a drying place for nets, neither shalt thou be built any more: for I have spoken it, saith the Lord God.", "bbe": "I will make you an uncovered rock: you will be a place for the stretching out of nets; there will be no building you up again: for I the Lord have said it, says the Lord.", "geneva": "I wil lay thee like the top of a rocke: thou shalt be for a spreading of nets: thou shalt be built no more: for I the Lord haue spoken it, sayth the Lord God.", "wycliffe": "and Y schal yyue thee in to a moost cleer stoon. Thou schalt be driyng of nettis, and thou schalt no more be bildid, for Y the Lord spak, seith the Lord God.", "rotherham": "And I will make of thee the glaring face of a cliff. A place for the spreading of nets, shalt thou become, Thou shalt not be but any more, For I. Yahweh have spoken it, Declareth My Lord Yahweh.", "darby": "And I will make thee a bare rock; thou shalt be [a place] for the spreading of nets; thou shalt be built no more: for I Jehovah have spoken [it], saith the Lord Jehovah.", "twenty": "", "jps": "And I will make thee a bare rock; thou shalt be a place for the spreading of nets, thou shalt be built no more; for I HaShem have spoken, saith the L-rd GOD.", "acv": "And I will make thee a bare rock; thou shall be a place for the spreading of nets. Thou shall be built no more, for I Jehovah have spoken it, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will make thee like a naked rock; thou shalt be a place to spread nets upon; thou shalt be built no more; for I, Jehovah, have spoken it, saith the Lord Jehovah.", "webster": "And I will make thee like the top of a rock: thou shalt be [a place] to spread nets upon; thou shalt be built no more: for I the LORD have spoken [it], saith the Lord GOD.", "vulgate": "et dabo te in limpidissimam petram siccatio sagenarum eris nec aedificaberis ultra quia ego locutus sum dicit Dominus Deus;", "brenton": "And I will make thee a bare rock: thou shalt be a place to spread nets upon; thou shalt be built no more: for I the Lord have spoken it, saith the Lord."}}, {"v": 15, "ref": "26:15", "o": "כֹּ֥ה אָמַ֛ר אֲדֹנָ֥/י יְהוִ֖ה לְ/צ֑וֹר הֲ/לֹ֣א מִ/קּ֣וֹל מַפַּלְתֵּ֗/ךְ בֶּ/אֱנֹ֨ק חָלָ֜ל בֵּ/הָ֤רֵֽג הֶ֨רֶג֙ בְּ/תוֹכֵ֔/ךְ יִרְעֲשׁ֖וּ הָ/אִיִּֽים", "en": {"kjv": "Thus saith the Lord God to Tyrus; Shall not the isles shake at the sound of thy fall, when the wounded cry, when the slaughter is made in the midst of thee?", "web": "Thus says the Lord Yahweh to Tyre: shall not the islands shake at the sound of your fall, when the wounded groan, when the slaughter is made in your midst?", "bsb": "This is what the Lord GOD says to Tyre: ‘Will not the coastlands quake at the sound of your downfall, when the wounded groan at the slaughter in your midst?", "asv": "Thus saith the Lord Jehovah to Tyre: shall not the isles shake at the sound of thy fall, when the wounded groan, when the slaughter is made in the midst of thee?", "ylt": "Thus said the Lord Jehovah to Tyre: Do not--from the noise of thy fall, In the groaning of the wounded, In the slaying of the slaughter in thy midst, The isles shake?", "dra": "Thus saith the Lord God to Tyre: Shall not the islands shake at the sound of thy fall, and the groans of thy slain when they shall be killed in the midst of thee?", "bbe": "This is what the Lord has said to Tyre: Will not the sea-lands be shaking at the sound of your fall, when the wounded give cries of pain, when men are put to the sword in you?", "geneva": "Thus sayth the Lord God to Tyrus, Shall not the yles tremble at the sounde of thy fall? and at the crie of the wounded, when they shall be slaine and murthered in the middes of thee?", "wycliffe": "The Lord God seith these thingis of Tire, Whether ilis schulen not be moued of the sown of thi fal, and of weiling of thi slayn men, whanne thei ben slayn in the myddis of thee?", "rotherham": "Thus saith My Lord. Yahweh, to Tyre: Shall it not be that. At the sound of thy fall. With the groan of thy pierced one. With the slaughter made in thy midst, The Coastlands shall tremble?", "darby": "Thus saith the Lord Jehovah to Tyre: Shall not the isles shake at the sound of thy fall, when the wounded groan, when the slaughter is made in the midst of thee?", "twenty": "", "jps": "Thus saith the L-rd GOD to Tyre: Shall not the isles shake at the sound of thy fall, when the wounded groan, when the slaughter is made in the midst of thee?", "acv": "Thus says the lord Jehovah to Tyre: Shall not the isles shake at the sound of thy fall, when the wounded groan, when the slaughter is made in the midst of thee?", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah to Tyre: Behold, the isles shall shake at the sound of thy fall, at the groaning of the wounded, and at the slaughter which is made in the midst of thee.", "webster": "Thus saith the Lord GOD to Tyre; Shall not the isles shake at the sound of thy fall, when the wounded cry, when the slaughter is made in the midst of thee?", "vulgate": "haec dicit Dominus Deus Tyro numquid non a sonitu ruinae tuae et gemitu interfectorum tuorum cum occisi fuerint in medio tui commovebuntur insulae;", "brenton": "For thus saith the Lord God to Sor; Shall not the isles shake at the sound of thy fall, while the wounded are groaning, while they have drawn a sword in the midst of thee?"}}, {"v": 16, "ref": "26:16", "o": "וְֽ/יָרְד֞וּ מֵ/עַ֣ל כִּסְאוֹתָ֗/ם כֹּ֚ל נְשִׂיאֵ֣י הַ/יָּ֔ם וְ/הֵסִ֨ירוּ֙ אֶת מְעִ֣ילֵי/הֶ֔ם וְ/אֶת בִּגְדֵ֥י רִקְמָתָ֖/ם יִפְשֹׁ֑טוּ חֲרָד֤וֹת יִלְבָּ֨שׁוּ֙ עַל הָ/אָ֣רֶץ יֵשֵׁ֔בוּ וְ/חָֽרְדוּ֙ לִ/רְגָעִ֔ים וְ/שָׁמְמ֖וּ עָלָֽיִ/ךְ", "en": {"kjv": "Then all the princes of the sea shall come down from their thrones, and lay away their robes, and put off their broidered garments: they shall clothe themselves with trembling; they shall sit upon the ground, and shall tremble at every moment, and be astonished at thee.", "web": "Then all the princes of the sea shall come down from their thrones, and lay aside their robes, and strip off their embroidered garments: they shall clothe themselves with trembling; they shall sit on the ground, and shall tremble every moment, and be astonished at you.", "bsb": "All the princes of the sea will descend from their thrones, remove their robes, and strip off their embroidered garments. Clothed with terror, they will sit on the ground, trembling every moment, appalled over you.", "asv": "Then all the princes of the sea shall come down from their thrones, and lay aside their robes, and strip off their broidered garments: they shall clothe themselves with trembling; they shall sit upon the ground, and shall tremble every moment, and be astonished at thee.", "ylt": "And come down from off their thrones have all princes of the sea, And they have turned aside their robes, And their embroidered garments strip off, Trembling they put on, on the earth they sit, And they have trembled every moment, And they have been astonished at thee,", "dra": "Then all the princes of the sea shall come down from their thrones: and take off their robes, and cast away their broidered garments, and be clothed with astonishment: they shall sit on the ground, and with amazement shall wonder at thy sudden fall.", "bbe": "Then all the rulers of the sea will come down from their high seats, and put away their robes and take off their clothing of needlework: they will put on the clothing of grief, they will take their seats on the earth, shaking with fear every minute and overcome with wonder at you.", "geneva": "Then all the princes of the sea shall come downe from their thrones: they shall lay away their robes, and put off their broydered garments, and shall clothe themselues with astonishment: they shall sitte vpon the ground, and be astonished at euery moment, and be amased at thee.", "wycliffe": "And alle the princis of the see schulen go doun of her seetis, and thei schulen do awei her mentils, ether spuylis of slayn enemyes, and thei schulen caste awei her dyuerse clothis, and shulen be clothid with wondring. Thei shulen sitte in the erthe, and thei shulen be astonyed, and thei shulen wondre of thi sodeyn fal.", "rotherham": "Then shall come down from off their thrones all the princes of the sea, And shall lay aside their robes. And their embroidered garments, shall strip off,— With tremblings, shall they clothe them. selves Upon the ground, shall they sit, And shall tremble every moment and be astonished over thee.", "darby": "And all the princes of the sea shall come down from their thrones, and lay aside their robes, and put off their broidered garments: they shall clothe themselves with trembling, they shall sit upon the ground, and shall tremble [every] moment, and be astonied because of thee.", "twenty": "", "jps": "Then all the princes of the sea shall come down from their thrones, and lay away their robes, and strip off their richly woven garments; they shall clothe themselves with trembling; they shall sit upon the ground, and shall tremble every moment, and be appalled at thee.", "acv": "Then all the rulers of the sea shall come down from their thrones, and lie aside their robes, and strip off their broidered garments. They shall clothe themselves with trembling. They shall sit upon the ground, and shall tremble every moment, and be astonished at thee.", "anderson": "", "haweis": "", "noyes": "And all the princes of the sea shall come down from their thrones, and lay aside their mantles, and put off their embroidered garments. They shall clothe themselves with trembling, and sit on the ground, and tremble every moment, and be astonished at thee.", "webster": "Then all the princes of the sea shall come down from their thrones, and lay away their robes, and put off their broidered garments: they shall clothe themselves with trembling; they shall sit upon the ground, and shall tremble at [every] moment, and be astonished at thee.", "vulgate": "et descendent de sedibus suis omnes principes maris et auferent exuvias suas et vestimenta sua varia abicient et induentur stupore in terra sedebunt et adtoniti super repentino casu tuo admirabuntur;", "brenton": "And all the princes of the nations of the sea shall come down from their thrones, and shall take off their crowns from their heads, and shall take off their embroidered raiment: they shall be utterly amazed; they shall sit upon the ground, and fear their own destruction, and shall groan over thee."}}, {"v": 17, "ref": "26:17", "o": "וְ/נָשְׂא֨וּ עָלַ֤יִ/ךְ קִינָה֙ וְ/אָ֣מְרוּ לָ֔/ךְ אֵ֣יךְ אָבַ֔דְתְּ נוֹשֶׁ֖בֶת מִ/יַּמִּ֑ים הָ/עִ֣יר הַ/הֻלָּ֗לָה אֲשֶׁר֩ הָיְתָ֨ה חֲזָקָ֤ה בַ/יָּם֙ הִ֣יא וְ/יֹשְׁבֶ֔י/הָ אֲשֶׁר נָתְנ֥וּ חִתִּיתָ֖/ם לְ/כָל יוֹשְׁבֶֽי/הָ", "en": {"kjv": "And they shall take up a lamentation for thee, and say to thee, How art thou destroyed, that wast inhabited of seafaring men, the renowned city, which wast strong in the sea, she and her inhabitants, which cause their terror to be on all that haunt it!", "web": "They shall take up a lamentation over you, and tell you, How you are destroyed, who were inhabited by seafaring men, the renowned city, who was strong in the sea, she and her inhabitants, who caused their terror to be on all who lived there!", "bsb": "Then they will lament for you, saying, “How you have perished, O city of renown inhabited by seafaring men— she who was powerful on the sea, along with her people, who imposed terror on all peoples!", "asv": "And they shall take up a lamentation over thee, and say to thee, How art thou destroyed, that wast inhabited by seafaring men, the renowned city, that was strong in the sea, she and her inhabitants, that caused their terror to be on all that dwelt there!", "ylt": "And have lifted up for thee a lamentation, And said to thee: How hast thou perished, That art inhabited from the seas, The praised city, that was strong in the sea, She and her inhabitants, Who put their terror on all her inhabitants!", "dra": "And taking up a lamentation over thee, they shall say to thee: How art thou fallen, that dwellest in the sea, renowned city that wast strong in the sea, with thy inhabitants whom all did dread?", "bbe": "And they will send up a song of grief for you, and say to you, What destruction has come on you, how are you cut off from the sea, the noted town, which was strong in the sea, she and her people, causing the fear of them to come on all the dry land!", "geneva": "And they shall take vp a lamentation for thee, and say to thee, Howe art thou destroyed, that wast inhabited of the sea men, the renoumed citie which was strong in the sea, both she and her inhabitants, which cause their feare to be on all that haunt therein!", "wycliffe": "And thei shulen take weilyng on thee, and schule seie to thee, Hou perischidist thou, noble citee, that dwellist in the see, that were strong in the see with thi dwelleris, whiche dwelleris alle men dredden?", "rotherham": "Then shall they take up over thee a dirge, And say to thee,- How hast thou perished, And ceased from the seas,- The city renowned which was strong in the sea She and they who dwelt in her, Who imparted their terror To all who dwelt in her.", "darby": "And they shall take up a lamentation for thee, and say to thee, How hast thou perished, that wast inhabited from the seas, O renowned city, which wast strong in the sea, — she and her inhabitants, who caused their terror to be on all them that dwell therein!", "twenty": "", "jps": "And they shall take up a lamentation for thee, and say to thee: how art thou destroyed, that wast peopled from the seas, the renowned city, that wast strong in the sea, thou and thy inhabitants, that caused your terror to be on all that inhabit the earth!", "acv": "And they shall take up a lamentation over thee, and say to thee, How thou are destroyed, who were inhabited by seafaring men, the renowned city that was strong in the sea, she and her inhabitants, who caused their terror to be on all who dwelt there!", "anderson": "", "haweis": "", "noyes": "And they shall utter a lamentation over thee, and say to thee, \"How art thou destroyed, thou that wast peopled from the seas, the renowned city, that wast mighty upon the sea, thou and thine inhabitants, causing terror to all that dwelt near thee!\"", "webster": "And they shall take up a lamentation for thee, and say to thee, How art thou destroyed, [that wast] inhabited by sea-faring men, the renowned city, which wast strong in the sea, she and her inhabitants, who cause their terror [to be] on all that haunt it!", "vulgate": "et adsumentes super te lamentum dicent tibi quomodo peristi quae habitas in mari urbs inclita quae fuisti fortis in mari cum habitatoribus tuis quos formidabant universi;", "brenton": "And they shall take up a lamentation for thee, and shall say to thee, How art thou destroyed from out of the sea, the renowned city, that brought her terror upon all her inhabitants."}}, {"v": 18, "ref": "26:18", "o": "עַתָּה֙ יֶחְרְד֣וּ הָֽ/אִיִּ֔ן י֖וֹם מַפַּלְתֵּ֑/ךְ וְ/נִבְהֲל֛וּ הָ/אִיִּ֥ים אֲשֶׁר בַּ/יָּ֖ם מִ/צֵּאתֵֽ/ךְ", "en": {"kjv": "Now shall the isles tremble in the day of thy fall; yea, the isles that are in the sea shall be troubled at thy departure.", "web": "Now shall the islands tremble in the day of your fall; yes, the islands that are in the sea shall be dismayed at your departure.", "bsb": "Now the coastlands tremble on the day of your downfall; the islands in the sea are dismayed by your demise.”’", "asv": "Now shall the isles tremble in the day of thy fall; yea, the isles that are in the sea shall be dismayed at thy departure.", "ylt": "Now they tremble, is it not the day of thy fall? Troubled have been the isles that are in the sea, at thine outgoing.", "dra": "Now shall the ships be astonished in the day of thy terror: and the islands in the sea shall be troubled because no one cometh out of thee.", "bbe": "Now the sea-lands will be shaking in the day of your fall; and all the ships on the sea will be overcome with fear at your going.", "geneva": "Nowe shall the yles be astonished in the day of thy fall: yea, the yles that are in the sea, shall be troubled at thy departure.", "wycliffe": "Now schippis schulen wondre in the dai of thi drede, and ilis in the see schulen be disturblid, for noon goith out of thee.", "rotherham": "Now, shall tremble the Coastlands, In the day of thy fall,- And shall shudder the isles that are in the sea. At thine exit!", "darby": "Now shall the isles tremble in the day of thy fall; and the isles that are in the sea shall be troubled at thy departure.", "twenty": "", "jps": "Now shall the isles tremble in the day of thy fall; yea, the isles that are in the sea shall be affrighted at thy going out.", "acv": "Now the isles shall tremble in the day of thy fall. Yea, the isles that are in the sea shall be dismayed at thy departure.", "anderson": "", "haweis": "", "noyes": "Now shall the isles tremble in the day of thy fall; yea, the isles that are in the sea shall quake at thy departure.", "webster": "Now shall the isles tremble in the day of thy fall; yes, the isles that [are] in the sea shall be disturbed at thy departure.", "vulgate": "nunc stupebunt naves in die pavoris tui et turbabuntur insulae in mari eo quod nullus egrediatur ex te;", "brenton": "And the isles shall be alarmed at the day of thy fall."}}, {"v": 19, "ref": "26:19", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה בְּ/תִתִּ֤/י אֹתָ/ךְ֙ עִ֣יר נֶחֱרֶ֔בֶת כֶּ/עָרִ֖ים אֲשֶׁ֣ר לֹֽא נוֹשָׁ֑בוּ בְּ/הַעֲל֤וֹת עָלַ֨יִ/ךְ֙ אֶת תְּה֔וֹם וְ/כִסּ֖וּ/ךְ הַ/מַּ֥יִם הָ/רַבִּֽים", "en": {"kjv": "For thus saith the Lord God; When I shall make thee a desolate city, like the cities that are not inhabited; when I shall bring up the deep upon thee, and great waters shall cover thee;", "web": "For thus says the Lord Yahweh: When I shall make you a desolate city, like the cities that are not inhabited; when I shall bring up the deep on you, and the great waters shall cover you;", "bsb": "For this is what the Lord GOD says: ‘When I make you a desolate city like other deserted cities, and when I raise up the deep against you so that the mighty waters cover you,", "asv": "For thus saith the Lord Jehovah: When I shall make thee a desolate city, like the cities that are not inhabited; when I shall bring up the deep upon thee, and the great waters shall cover thee;", "ylt": "For thus said the Lord Jehovah: In my making thee a city wasted, Like cities that have not been inhabited, In bringing up against thee the deep, Then covered thee have the great waters.", "dra": "For thus saith the Lord God: When I shall make thee a desolate city like the cities that are not inhabited: and shall bring the deep upon thee, and many waters shall cover thee:", "bbe": "For this is what the Lord has said: I will make you a waste town, like the towns which are unpeopled; when I make the deep come upon you, covering you with great waters.", "geneva": "For thus saith the Lord God, When I shall make thee a desolate citie, like ye cities that are not inhabited, and when I shall bring the deepe vpon thee, and great waters shall couer thee,", "wycliffe": "For the Lord God seith these thingis, Whanne Y schal yyue thee a citee desolat, as the citees that ben not enhabitid, and Y schal bringe on thee the depthe of watris, and many watris schulen hile thee.", "rotherham": "For thus saith My Lord Yahweh, When I make thee a desolate city, Like cities which cannot be dwelt in,- When I bring up over thee the roaring deep, And the mighty waters cover thee,", "darby": "For thus saith the Lord Jehovah: When I shall make thee a desolate city, like the cities that are not inhabited; when I bring up the deep upon thee, and the great waters cover thee:", "twenty": "", "jps": "For thus saith the L-rd GOD: When I shall make thee a desolate city, like the cities that are not inhabited; when I shall bring up the deep upon thee, and the great waters shall cover thee;", "acv": "For thus says the lord Jehovah: When I shall make thee a desolate city, like the cities that are not inhabited, when I shall bring up the deep upon thee, and the great waters shall cover thee,", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: When I shall make thee a desolate city, like the cities that are not inhabited, when I shall bring up the deep upon thee, and great waters shall cover thee,", "webster": "For thus saith the Lord GOD; When I shall make thee a desolate city, like the cities that are not inhabited; when I shall bring up the deep upon thee, and great waters shall cover thee;", "vulgate": "quia haec dicit Dominus Deus cum dedero te urbem desolatam sicut civitates quae non habitantur et adduxero super te abyssum et operuerint te aquae multae;", "brenton": "For thus saith the Lord God; When I shall make the city desolate, as the cities that shall not be inhabited, when I have brought the deep up upon thee,"}}, {"v": 20, "ref": "26:20", "o": "וְ/הוֹרַדְתִּי/ךְ֩ אֶת י֨וֹרְדֵי ב֜וֹר אֶל עַ֣ם עוֹלָ֗ם וְ֠/הוֹשַׁבְתִּי/ךְ בְּ/אֶ֨רֶץ תַּחְתִּיּ֜וֹת כָּ/חֳרָב֤וֹת מֵֽ/עוֹלָם֙ אֶת י֣וֹרְדֵי ב֔וֹר לְמַ֖עַן לֹ֣א תֵשֵׁ֑בִי וְ/נָתַתִּ֥י צְבִ֖י בְּ/אֶ֥רֶץ חַיִּֽים", "en": {"kjv": "When I shall bring thee down with them that descend into the pit, with the people of old time, and shall set thee in the low parts of the earth, in places desolate of old, with them that go down to the pit, that thou be not inhabited; and I shall set glory in the land of the living;", "web": "then I will bring you down with those who descend into the pit, to the people of old time, and will make you to dwell in the lower parts of the earth, in the places that are desolate of old, with those who go down to the pit, that you be not inhabited; and I will set glory in the land of the living:", "bsb": "then I will bring you down with those who descend to the Pit, to the people of antiquity. I will make you dwell in the earth below like the ancient ruins, with those who descend to the Pit, so that you will no longer be inhabited or set in splendor in the land of the living.", "asv": "then will I bring thee down with them that descend into the pit, to the people of old time, and will make thee to dwell in the nether parts of the earth, in the places that are desolate of old, with them that go down to the pit, that thou be not inhabited; and I will set glory in the land of the living.", "ylt": "And I have caused thee to go down, With those going down to the pit, Unto the people of old, And I have caused thee to dwell in the land, The lower parts--in wastes of old, With those going down to the pit, So that thou art not inhabited, And I have given beauty in the land of the living.", "dra": "And when I shall bring thee down with those that descend into the pit to the everlasting people, and shall set thee in the lowest parts of the earth, as places desolate of old, with them that are brought down into the pit, that thou be not inhabited: and when I shall give glory in the land of the living,", "bbe": "Then I will make you go down with those who go down into the underworld, to the people of the past, causing your living-place to be in the deepest parts of the earth, in places long unpeopled, with those who go down into the deep, so that there will be no one living in you; and you will have no glory in the land of the living.", "geneva": "When I shall cast thee downe with them that descende into the pitte, with the people of olde time, and shall set thee in the lowe partes of the earth, like the olde ruines, with them, I say, which goe downe to the pitte, so that thou shalt not be inhabited, and I shall shewe my glory in the land of the liuing,", "wycliffe": "And Y schal drawe thee doun with hem that goon doun in to a lake, to the puple euerlastynge; and Y schal sette thee in the laste lond, as elde wildirnessis, with hem that ben led doun in to a lake, that thou be not enhabited. Certis whanne Y schal yyue glorye in the lond of lyueris,", "rotherham": "Then will I bring thee down with them that go down into the pit. Unto the people of age-past times And cause thee to dwell in the earth below Among the desolations from age-past times With them that go down into the pit That thou mayest not be dwelt in, Nor yet present thyself in the land of the living.", "darby": "then will I bring thee down, with them that go down to the pit, to the people of old time, and will cause thee to dwell in the lower parts of the earth, in places desolate of old, with them that go down to the pit, that thou be not inhabited; and I will set glory in the land of the living.", "twenty": "", "jps": "then will I bring thee down with them that descend into the pit, to the people of old time, and will make thee to dwell in the nether parts of the earth, like the places that are desolate of old, with them that go down to the pit, that thou be not inhabited; and I will set glory in the land of the living;", "acv": "then I will bring thee down with those who descend into the pit, to the people of old time, and will make thee to dwell in the nether parts of the earth, in the places that are desolate of old, with those who go down to the pit, that thou not be inhabited. And I will set glory in the land of the living.", "anderson": "", "haweis": "", "noyes": "I will bring thee down to them that have gone down to the pit, to the people of old time, and I will cause thee to dwell in the lower parts of the earth, amid the ruins of ancient times, with them that have gone down to the pit, that thou be no more inhabited; but I will set glory in the land of the living.", "webster": "When I shall bring thee down with them that descend into the pit, with the people of old time, and shall set thee in the low parts of the earth, in places desolate of old, with them that go down to the pit, that thou be not inhabited; and I shall set glory in the land of the living;", "vulgate": "et detraxero te cum his qui descendunt in lacum ad populum sempiternum et conlocavero te in terra novissima sicut solitudines veteres cum his qui deducuntur in lacum ut non habiteris porro dedero gloriam in terra viventium;", "brenton": "and great waters shall cover thee; and I shall bring thee down to them that go down to the pit, to the people of old time, and shall cause thee to dwell in the depths of the earth, as in everlasting desolation, with them that go down to the pit, that thou mayest not be inhabited, nor stand upon the land of life;"}}, {"v": 21, "ref": "26:21", "o": "בַּלָּה֥וֹת אֶתְּנֵ֖/ךְ וְ/אֵינֵ֑/ךְ וּֽ/תְבֻקְשִׁ֗י וְ/לֹֽא תִמָּצְאִ֥י עוֹד֙ לְ/עוֹלָ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "I will make thee a terror, and thou shalt be no more: though thou be sought for, yet shalt thou never be found again, saith the Lord God.", "web": "I will make you a terror, and you shall no more have any being; though you are sought for, yet you will never be found again, says the Lord Yahweh.", "bsb": "I will make you an object of horror, and you will be no more. You will be sought, but will never be found,’ declares the Lord GOD.”", "asv": "I will make thee a terror, and thou shalt no more have any being; though thou be sought for, yet shalt thou never be found again, saith the Lord Jehovah.", "ylt": "Wastes I do make thee, and thou art not, And thou art sought, and art not found any more--to the age, An affirmation of the Lord Jehovah!'", "dra": "I will bring thee to nothing, and thou shalt not be, and if thou be sought for, thou shalt not be found any more for ever, saith the Lord God.", "bbe": "I will make you a thing of fear, and you will come to an end: even if you are looked for, you will not be seen again for ever, says the Lord.", "geneva": "I will bring thee to nothing, and thou shalt be no more: though thou be sought for, yet shalt thou neuer be found againe, sayth the Lord God.", "wycliffe": "Y schal dryue thee in to nouyt, and thou schalt not be; and thou schalt be souyt, and thou schalt no more be foundun with outen ende, seith the Lord God.", "rotherham": "A terror, will I make thee And thou shalt not be: Though thou be sought for, Thou shalt not be found any more To times age-abiding, Declareth My Lord, Yahweh.", "darby": "And I will make thee a terror, and thou shalt be no [more]; and thou shalt be sought for, and shalt never be found again, for ever, saith the Lord Jehovah.", "twenty": "", "jps": "I will make thee a terror, and thou shalt be no more; though thou be sought for, yet shalt thou never be found again, saith the L-rd GOD.'", "acv": "I will make thee a horror, and thou shall no more have any being. Though thou be sought for, yet thou shall never be found again, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "I will make thee a desolation, and thou shalt be no more; though thou be sought for, thou shalt be found no more forever, saith the Lord Jehovah.", "webster": "I will make thee a terror, and thou [shalt be] no [more]: though thou shalt be sought for, yet shalt thou never be found again, saith the Lord GOD.", "vulgate": "in nihilum redigam te et non eris et requisita non invenieris ultra in sempiternum dicit Dominus Deus;", "brenton": "I will make thee a destruction, and thou shalt be no more for ever, saith the Lord God."}}]}, {"c": 27, "verses": [{"v": 1, "ref": "27:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came again to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "The word of Jehovah came again unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "The word of the Lord came to me again, saying,", "geneva": "The worde of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying:", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came again to me, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came again to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me saying,"}}, {"v": 2, "ref": "27:2", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם שָׂ֥א עַל צֹ֖ר קִינָֽה", "en": {"kjv": "Now, thou son of man, take up a lamentation for Tyrus;", "web": "You, son of man, take up a lamentation over Tyre;", "bsb": "“Now you, son of man, take up a lament for Tyre.", "asv": "And thou, son of man, take up a lamentation over Tyre;", "ylt": "`And thou, son of man, lift up concerning Tyre a lamentation, and thou hast said to Tyre:", "dra": "Thou therefore, O son of man, take up a lamentation for Tyre:", "bbe": "And you, son of man, make a song of grief for Tyre;", "geneva": "Sonne of man, take vp a lametation for Tyrus,", "wycliffe": "and he seide, Therfor thou, sone of man, take weilyng on Tire.", "rotherham": "Thou, therefore, son of man, Take up over Tyre a dirge;", "darby": "And thou, son of man, take up a lamentation for Tyre,", "twenty": "", "jps": "'And thou, son of man, take up a lamentation for Tyre,", "acv": "And thou, son of man, take up a lamentation over Tyre,", "anderson": "", "haweis": "", "noyes": "Son of man, take up a lamentation over Tyre,", "webster": "Now, thou son of man, take up a lamentation for Tyre;", "vulgate": "tu ergo fili hominis adsume super Tyrum lamentum;", "brenton": "And thou, son of man, take up a lamentation against Sor;"}}, {"v": 3, "ref": "27:3", "o": "וְ/אָמַרְתָּ֣ לְ/צ֗וֹר ה/ישבתי הַ/יֹּשֶׁ֨בֶת֙ עַל מְבוֹאֹ֣ת יָ֔ם רֹכֶ֨לֶת֙ הָֽ/עַמִּ֔ים אֶל אִיִּ֖ים רַבִּ֑ים כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה צ֕וֹר אַ֣תְּ אָמַ֔רְתְּ אֲנִ֖י כְּלִ֥ילַת יֹֽפִי", "en": {"kjv": "And say unto Tyrus, O thou that art situate at the entry of the sea, which art a merchant of the people for many isles, Thus saith the Lord God; O Tyrus, thou hast said, I am of perfect beauty.", "web": "and tell Tyre, you who dwell at the entry of the sea, who are the merchant of the peoples to many islands, thus says the Lord Yahweh: You, Tyre, have said, I am perfect in beauty.", "bsb": "Tell Tyre, who dwells at the gateway to the sea, merchant of the peoples on many coasts, that this is what the Lord GOD says: You have said, O Tyre, ‘I am perfect in beauty.’", "asv": "and say unto Tyre, O thou that dwellest at the entry of the sea, that art the merchant of the peoples unto many isles, thus saith the Lord Jehovah: Thou, O Tyre, hast said, I am perfect in beauty.", "ylt": "O dweller on the entrances of the sea, Merchant of the peoples unto many isles, Thus said the Lord Jehovah: O Tyre, thou--thou hast said: I am the perfection of beauty.", "dra": "And say to Tyre that dwelleth at the entry of the sea, being the mart of the people for many islands: Thus saith the Lord God: O Tyre, thou hast said: I am of perfect beauty,", "bbe": "And say to Tyre, O you who are seated at the doorway of the sea, trading for the peoples with the great sea-lands, these are the words of the Lord: You, O Tyre, have said, I am a ship completely beautiful.", "geneva": "And say vnto Tyrus, that is situate at the entrie of the sea, which is the marte of the people for many yles, Thus sayeth the Lord God, O Tyrus, thou hast said, I am of perfite beautie.", "wycliffe": "And thou schalt seie to Tire, that dwellith in the entryng of the see, to the marchaundie of puplis to many ilis, The Lord God seith these thingis, O! Tire, thou seidist, Y am of perfit fairnesse,", "rotherham": "And thou shalt say unto Tyre, O thou that dwellest by the entrances of the sea, Thou merchant of the peoples unto many shores,— Thus, saith My Lord, Yahweh, O Tyre, Thou saidst, I, am the perfection of beauty!", "darby": "and say unto Tyre: O thou that art situate at the entries of the sea, and traffickest with the peoples in many isles, thus saith the Lord Jehovah: Thou, Tyre, hast said, I am perfect in beauty.", "twenty": "", "jps": "and say unto Tyre, that dwelleth at the entry of the sea, that is the merchant of the peoples unto many isles: Thus saith the L-rd GOD: thou, O Tyre, hast said: I am of perfect beauty.", "acv": "and say to Tyre, O thou that dwells at the entry of the sea, that is the merchant of the peoples to many isles, thus says the lord Jehovah: Thou, O Tyre, have said, I am perfect in beauty.", "anderson": "", "haweis": "", "noyes": "and say to Tyre, O thou that didst dwell at the entrance of the sea, the merchant of the nations to many coasts! thus saith the Lord Jehovah: O Tyre, thou hast said, \"I am perfect in beauty.\"", "webster": "And say to Tyre, O thou that art situated at the entry of the sea, [which art] a merchant of the people for many isles, Thus saith the Lord GOD; O Tyre, thou hast said, I [am] of perfect beauty.", "vulgate": "et dices Tyro quae habitat in introitu maris negotiationi populorum ad insulas multas haec dicit Dominus Deus o Tyre tu dixisti perfecti decoris ego sum;", "brenton": "and thou shalt say to Sor that dwells at the entrance of the sea, to the mart of the nations coming from many islands, Thus saith the Lord to Sor; Thou hast said, I have clothed myself with my beauty."}}, {"v": 4, "ref": "27:4", "o": "בְּ/לֵ֥ב יַמִּ֖ים גְּבוּלָ֑יִ/ךְ בֹּנַ֕יִ/ךְ כָּלְל֖וּ יָפְיֵֽ/ךְ", "en": {"kjv": "Thy borders are in the midst of the seas, thy builders have perfected thy beauty.", "web": "Your borders are in the heart of the seas; your builders have perfected your beauty.", "bsb": "Your borders are in the heart of the seas; your builders perfected your beauty.", "asv": "Thy borders are in the heart of the seas; thy builders have perfected thy beauty.", "ylt": "In the heart of the seas are thy borders, Thy builders have perfected thy beauty.", "dra": "And situate in the heart of the sea. Thy neighbours, that built thee, have perfected thy beauty:", "bbe": "Your builders have made your outlines in the heart of the seas, they have made you completely beautiful.", "geneva": "Thy borders are in the middes of the sea, and thy builders haue made thee of perfit beauty.", "wycliffe": "and Y am set in the herte of the see. Thei that ben in thi coostis that bildiden thee, filliden thi fairnesse;", "rotherham": "In the heart of the seas, were thy bounds, —Thy builders perfected thy beauty:", "darby": "Thy borders are in the heart of the seas, thy builders have perfected thy beauty.", "twenty": "", "jps": "Thy borders are in the heart of the seas, thy builders have perfected thy beauty.", "acv": "Thy borders are in the heart of the seas. Thy builders have perfected thy beauty.", "anderson": "", "haweis": "", "noyes": "Thy borders are in the midst of the seas; thy builders have perfected thy beauty.", "webster": "Thy borders [are] in the midst of the seas, thy builders have perfected thy beauty.", "vulgate": "et in corde maris sita finitimi tui qui te aedificaverunt impleverunt decorem tuum;", "brenton": "In the heart of the sea thy sons have put beauty upon thee for Beelim."}}, {"v": 5, "ref": "27:5", "o": "בְּרוֹשִׁ֤ים מִ/שְּׂנִיר֙ בָּ֣נוּ לָ֔/ךְ אֵ֖ת כָּל לֻֽחֹתָ֑יִם אֶ֤רֶז מִ/לְּבָנוֹן֙ לָקָ֔חוּ לַ/עֲשׂ֥וֹת תֹּ֖רֶן עָלָֽיִ/ךְ", "en": {"kjv": "They have made all thy ship boards of fir trees of Senir: they have taken cedars from Lebanon to make masts for thee.", "web": "They have made all your planks of fir trees from Senir; they have taken a cedar from Lebanon to make a mast for you.", "bsb": "They constructed all your planking with cypress from Senir. They took a cedar from Lebanon to make a mast for you.", "asv": "They have made all thy planks of fir-trees from Senir; they have taken a cedar from Lebanon to make a mast for thee.", "ylt": "Of firs of Senir they have built to thee all thy double-boarded ships, Of cedars of Lebanon they have taken to make a mast for thee,", "dra": "With fir trees of Sanir they have built thee with all sea planks: they have taken cedars from Libanus to make thee masts.", "bbe": "They have made all your boards of fir-trees from Senir: they have taken cedars from Lebanon to make the supports for your sails.", "geneva": "They haue made all thy shippe boardes of firre trees of Shenir: they haue brought cedars from Lebanon, to make mastes for thee.", "wycliffe": "thei bildiden thee with fir trees of Sanyr, with alle werkis of boordis of the see; thei token a cedre of the Liban, to make a mast to thee.", "rotherham": "With fir-trees from Senir, but they for thee all the two-decked vessels,— Cedar from Lebanon, fetched they, to make masts for thee:", "darby": "They made all thy double boards of cypress-trees of Senir; they took cedars from Lebanon to make masts for thee.", "twenty": "", "jps": "Of cypress-trees from Senir have they fashioned all thy planks; they have taken cedars from Lebanon to make masts for thee.", "acv": "They have made all thy planks of fir trees from Senir. They have taken a cedar from Lebanon to make a mast for thee.", "anderson": "", "haweis": "", "noyes": "They made all thy ship-boards of cypresses of Senir; they took cedars from Lebanon to make masts for thee.", "webster": "They have made all thy [ship]-boards of fir-trees of Senir: they have taken cedars from Lebanon to make masts for thee.", "vulgate": "abietibus de Sanir extruxerunt te cum omnibus tabulatis maris cedrum de Libano tulerunt ut facerent tibi malum;", "brenton": "Cedar in Senir was employed for thee in building: boards of cypress timber were taken out of Libanus, and wood to make thee masts of fir."}}, {"v": 6, "ref": "27:6", "o": "אַלּוֹנִים֙ מִ/בָּ֔שָׁן עָשׂ֖וּ מִשּׁוֹטָ֑יִ/ךְ קַרְשֵׁ֤/ךְ עָֽשׂוּ שֵׁן֙ בַּת אֲשֻׁרִ֔ים מֵ/אִיֵּ֖י כתים כִּתִּיִּֽים", "en": {"kjv": "Of the oaks of Bashan have they made thine oars; the company of the Ashurites have made thy benches of ivory, brought out of the isles of Chittim.", "web": "Of the oaks of Bashan have they made your oars; they have made your benches of ivory inlaid in boxwood, from the islands of Kittim.", "bsb": "Of oaks from Bashan they made your oars; of wood from the coasts of Cyprus they made your deck, inlaid with ivory.", "asv": "Of the oaks of Bashan have they made thine oars; they have made thy benches of ivory inlaid in boxwood, from the isles of Kittim.", "ylt": "Of oaks of Bashan they made thine oars, Thy bench they have made of ivory, A branch of Ashurim from isles of Chittim.", "dra": "They have cut thy oars out of the oaks of Basan: and they have made thee benches of Indian ivory and cabins with things brought from the islands of Italy.", "bbe": "Of oak-trees from Bashan they have made your driving blades; they have made your floors of ivory and boxwood from the sea-lands of Kittim.", "geneva": "Of ye okes of Bashan haue they made thine ores: the company of the Assyrians haue made thy banks of yuorie, brought out of ye yles of Chittim.", "wycliffe": "Thei hewiden ookis of Bala in to thin ooris, thei maden to thee thi seetis of roweris of yuer of Ynde, and cabans of the ilis of Italie.", "rotherham": "With oaks from Bashan, made they thine oars,— Thy benches, made they of ivory, inlaid with boxwood, From the shores of the West:", "darby": "Of the oaks of Bashan did they make thine oars; they made thy benches of ivory, inlaid in box-wood, out of the isles of Chittim.", "twenty": "", "jps": "Of the oaks of Bashan have they made thine oars; thy deck have they made of ivory inlaid in larch, from the isles of the Kittites.", "acv": "Of the oaks of Bashan they have made thine oars. They have made thy benches of ivory inlaid in boxwood, from the isles of Kittim.", "anderson": "", "haweis": "", "noyes": "Of oaks of Bashan they made thine oars; thy benches they made of ivory inlaid in cedar from the coasts of the Chittaeans.", "webster": "[Of] the oaks of Bashan have they made thy oars; the company of the Ashurites have made thy benches [of] ivory, [brought] out of the isles of Chittim.", "vulgate": "quercus de Basan dolaverunt in remos tuos transtra tua fecerunt tibi ex ebore indico et praetoriola de insulis Italiae;", "brenton": "They made thine oars of wood out of the land of Basan; thy sacred utensils they made of ivory, thy shady houses of wood from the isles of Chetiim."}}, {"v": 7, "ref": "27:7", "o": "שֵׁשׁ בְּ/רִקְמָ֤ה מִ/מִּצְרַ֨יִם֙ הָיָ֣ה מִפְרָשֵׂ֔/ךְ לִ/הְי֥וֹת לָ֖/ךְ לְ/נֵ֑ס תְּכֵ֧לֶת וְ/אַרְגָּמָ֛ן מֵ/אִיֵּ֥י אֱלִישָׁ֖ה הָיָ֥ה מְכַסֵּֽ/ךְ", "en": {"kjv": "Fine linen with broidered work from Egypt was that which thou spreadest forth to be thy sail; blue and purple from the isles of Elishah was that which covered thee.", "web": "Of fine linen with embroidered work from Egypt was your sail, that it might be to you for a banner; blue and purple from the islands of Elishah was your awning.", "bsb": "Of embroidered fine linen from Egypt they made your sail, which served as your banner. Of blue and purple from the coasts of Elishah they made your awning.", "asv": "Of fine linen with broidered work from Egypt was thy sail, that it might be to thee for an ensign; blue and purple from the isles of Elishah was thine awning.", "ylt": "Of fine linen with embroidery from Egypt hath been thy sail, To be to thee for an ensign, Of blue and purple from isles of Elishah hath been thy covering.", "dra": "Fine broidered linen from Egypt was woven for thy sail, to be spread on thy mast: blue and purple from the islands of Elisa, were made thy covering.", "bbe": "The best linen with needlework from Egypt was your sail, stretched out to be a flag for you; blue and purple from the sea-lands of Elishah gave you shade.", "geneva": "Fine linen with broydered woorke, brought from Egypt, was spread ouer thee to be thy sayle, blue silke and purple, brought from the yles of Elishah, was thy couering.", "wycliffe": "Dyuerse biys, `ether whijt silk, of Egipt, was wouun to thee in to a veil, that it schulde be set in the mast; iacynct and purpur of the ilis of Elisa weren maad thin hiling.", "rotherham": "Of fine linen with embroidered work from Egypt, was thy sail, To serve thee for ensign,— Blue and purple from the shores of Aeolis became thine awning:", "darby": "Byssus with broidered work from Egypt was thy sail, to serve thee for a banner; blue and purple from the isles of Elishah was thine awning.", "twenty": "", "jps": "Of fine linen with richly woven work from Egypt was thy sail, that it might be to thee for an ensign; blue and purple from the isles of Elishah was thine awning.", "acv": "Of fine linen with broidered work from Egypt was thy sail, that it might be to thee for an ensign. Blue and purple from the isles of Elishah was thine awning.", "anderson": "", "haweis": "", "noyes": "Fine linen with broidered work from Egypt was that which thou didst spread forth to be thy sail; blue and purple from the coasts of Elisha were thy covering.", "webster": "Fine linen with broidered work from Egypt was that which thou spreadest forth to be thy sail; blue and purple from the isles of Elishah was that which covered thee.", "vulgate": "byssus varia de Aegypto texta est tibi in velum ut poneretur in malo hyacinthus et purpura de insulis Elisa facta sunt operimentum tuum;", "brenton": "Fine linen with embroidery from Egypt supplied the couch, to put honour upon thee, and to clothe thee with blue and purple from the isles of Elisai; and they became thy coverings."}}, {"v": 8, "ref": "27:8", "o": "יֹשְׁבֵ֤י צִידוֹן֙ וְ/אַרְוַ֔ד הָי֥וּ שָׁטִ֖ים לָ֑/ךְ חֲכָמַ֤יִ/ךְ צוֹר֙ הָ֣יוּ בָ֔/ךְ הֵ֖מָּה חֹבְלָֽיִ/ךְ", "en": {"kjv": "The inhabitants of Zidon and Arvad were thy mariners: thy wise men, O Tyrus, that were in thee, were thy pilots.", "web": "The inhabitants of Sidon and Arvad were your rowers: your wise men, Tyre, were in you, they were your pilots.", "bsb": "The men of Sidon and Arvad were your oarsmen. Your men of skill, O Tyre, were there as your captains.", "asv": "The inhabitants of Sidon and Arvad were thy rowers: thy wise men, O Tyre, were in thee, they were thy pilots.", "ylt": "Inhabitants of Zidon and Arvad have been rowers to thee, Thy wise men, O Tyre, have been in thee, They are thy pilots.", "dra": "The inhabitants of Sidon, and the Arabians were thy rowers: thy wise men, O Tyre, were thy pilots.", "bbe": "The people of Zidon and Arvad were your boatmen; the wise men of Zemer were in you; they were guiding your ships;", "geneva": "The inhabitants of Zidon, and Aruad were thy mariners, O Tyrus: thy wise men that were in thee, they were thy pilots.", "wycliffe": "The dwelleris of Sidon and Aradians weren thi roweris; Tire, thi wise men weren maad thi gouernouris.", "rotherham": "the inhabitants of Zidon and Arvad, Became rowers for thee,— Thine own skilled men O Tyre, were within thee, They were thy sailors:", "darby": "The inhabitants of Zidon and Arvad were thy rowers; thy wise men, O Tyre, who were in thee, were thy pilots.", "twenty": "", "jps": "The inhabitants of Sidon and Arvad were thy rowers; thy wise men, O Tyre, were in thee, they were thy pilots.", "acv": "The inhabitants of Sidon and Arvad were thy rowers. Thy wise men, O Tyre, were in thee; they were thy pilots.", "anderson": "", "haweis": "", "noyes": "The inhabitants of Zidon and Arvad were thy rowers; thy wise men, O Tyre, that were in thee, were thy pilots.", "webster": "The inhabitants of Zidon and Arvad were thy mariners: thy wise [men], O Tyre, [that] were in thee, were thy pilots.", "vulgate": "habitatores Sidonis et Aradii fuerunt remiges tui sapientes tui Tyre facti sunt gubernatores tui;", "brenton": "And thy princes were the dwellers in Sidon, and the Aradians were thy rowers: thy wise men, O Sor, who were in thee, these were thy pilots."}}, {"v": 9, "ref": "27:9", "o": "זִקְנֵ֨י גְבַ֤ל וַ/חֲכָמֶ֨י/הָ֙ הָ֣יוּ בָ֔/ךְ מַחֲזִיקֵ֖י בִּדְקֵ֑/ךְ כָּל אֳנִיּ֨וֹת הַ/יָּ֤ם וּ/מַלָּֽחֵי/הֶם֙ הָ֣יוּ בָ֔/ךְ לַ/עֲרֹ֖ב מַעֲרָבֵֽ/ךְ", "en": {"kjv": "The ancients of Gebal and the wise men thereof were in thee thy calkers: all the ships of the sea with their mariners were in thee to occupy thy merchandise.", "web": "The old men of Gebal and the wise men of it were in you your repairers of ship seams: all the ships of the sea with their mariners were in you to deal in your merchandise.", "bsb": "The elders of Gebal were aboard as shipwrights, repairing your leaks. All the ships of the sea and their sailors came alongside to barter for your merchandise.", "asv": "The old men of Gebal and the wise men thereof were in thee thy calkers: all the ships of the sea with their mariners were in thee to deal in thy merchandise.", "ylt": "Elders of Gebal and its wise men have been in thee, Strengthening thy breach; All ships of the sea and their mariners, Have been in thee, to trade with thy merchandise.", "dra": "The ancients of Gebal, and the wise men thereof furnished mariners for the service of thy various furniture: all the ships of the sea, and their mariners were thy factors.", "bbe": "The responsible men of Gebal and its wise men were in you, making your boards watertight: all the ships of the sea with their seamen were in you trading in your goods.", "geneva": "The ancients of Gebal, and the wise men thereof were in thee thy calkers, all the shippes of the sea with their mariners were in thee to occupie thy marchandise.", "wycliffe": "The elde men of Biblos, and the prudent men therof, hadden schipmen to the seruyse of thi dyuerse araye of houshold; alle the schippis of the see, and the schip men of tho, weren in the puple of thi marchaundie.", "rotherham": "the elders of Byblus and the skilled men thereof, were within thee, Thy calkers,— All the ships of the sea and their mariners, were within thee, To carry on thy traffic,", "darby": "The elders of Gebal and the wise men thereof were in thee repairing thy leaks; all the ships of the sea with their mariners were in thee, to barter with thee.", "twenty": "", "jps": "The elders of Gebal and the wise men thereof were in thee thy calkers; all the ships of the sea with their mariners were in thee to exchange thy merchandise.", "acv": "The old men of Gebal and the wise men thereof were thy caulkers in thee. All the ships of the sea with their mariners were in thee to deal in thy merchandise.", "anderson": "", "haweis": "", "noyes": "The ancients of Gebal and the skilful men thereof were in thee, thy calkers; all the ships of the sea, with their mariners, were in thee, to traffic in thy merchandise.", "webster": "The ancients of Gebal and its wise [men] were in thee thy calkers: all the ships of the sea with their mariners were in thee to occupy thy merchandise.", "vulgate": "senes Bibli et prudentes eius habuerunt nautas ad ministerium variae supellectilis tuae omnes naves maris et nautae earum fuerunt in populo negotiationis tuae;", "brenton": "The elders of the Biblians, and their wise men, who were in thee, these helped thy counsel: and all the ships of the sea and their rowers traded for thee to the utmost west."}}, {"v": 10, "ref": "27:10", "o": "פָּרַ֨ס וְ/ל֤וּד וּ/פוּט֙ הָי֣וּ בְ/חֵילֵ֔/ךְ אַנְשֵׁ֖י מִלְחַמְתֵּ֑/ךְ מָגֵ֤ן וְ/כוֹבַע֙ תִּלּוּ בָ֔/ךְ הֵ֖מָּה נָתְנ֥וּ הֲדָרֵֽ/ךְ", "en": {"kjv": "They of Persia and of Lud and of Phut were in thine army, thy men of war: they hanged the shield and helmet in thee; they set forth thy comeliness.", "web": "Persia and Lud and Put were in your army, your men of war: they hanged the shield and helmet in you; they showed your beauty.", "bsb": "Men of Persia, Lydia, and Put served as warriors in your army. They hung their shields and helmets on your walls; they gave you splendor.", "asv": "Persia and Lud and Put were in thine army, thy men of war: they hanged the shield and helmet in thee; they set forth thy comeliness.", "ylt": "Persian and Lud and Phut Have been in thy forces--thy men of war. Shield and helmet they hung up in thee, They--they have given out thine honour.", "dra": "The Persians, and Lydians, and the Libyans were thy soldiers in thy army: they hung up the buckler and the helmet in thee for thy ornament.", "bbe": "Cush and Lud and Put were in your army, your men of war, hanging up their body-covers and head-dresses of war in you: they gave you your glory.", "geneva": "They of Persia, and of Lud and of Phut were in thine armie: thy men of warre they hanged the shielde and helmet in thee: they set foorth thy beautie.", "wycliffe": "Perseis, and Lidians, and Libians weren in thin oost; thi men werriours hangiden in thee a scheeld and helm, for thin ournyng.", "rotherham": "They of Persia and Lud and Phut were in thine army, Thy men of war,— Shield and helmet, hung they up within thee, They set forth thy splendour:", "darby": "Persia and Lud and Phut were in thine army, thy men of war: they hanged shield and helmet in thee; they gave splendour to thee.", "twenty": "", "jps": "Persia and Lud and Put were in thine army, thy men of war; they hanged the shield and helmet in thee, they set forth thy comeliness.", "acv": "Persia and Lud and Put were in thine army, thy men of war. They hung the shield and helmet in thee. They set forth thy comeliness.", "anderson": "", "haweis": "", "noyes": "Persians, and Lydians, and Lybians were in thine army, thy men of war; they hung up the shield and helmet in thee; they set forth thy glory.", "webster": "They of Persia and of Lud and of Phut were in thy army, thy military men: they hung the shield and helmet in thee; they set forth thy comeliness.", "vulgate": "Persae et Lydi et Lybies erant in exercitu tuo viri bellatores tui clypeum et galeam suspenderunt in te pro ornatu tuo;", "brenton": "Persians and Lydians and Libyans were in thine army: thy warriors hung in thee shields and helmets; these gave thee thy glory."}}, {"v": 11, "ref": "27:11", "o": "בְּנֵ֧י אַרְוַ֣ד וְ/חֵילֵ֗ךְ עַל חוֹמוֹתַ֨יִ/ךְ֙ סָבִ֔יב וְ/גַ֨מָּדִ֔ים בְּ/מִגְדְּלוֹתַ֖יִ/ךְ הָי֑וּ שִׁלְטֵי/הֶ֞ם תִּלּ֤וּ עַל חוֹמוֹתַ֨יִ/ךְ֙ סָבִ֔יב הֵ֖מָּה כָּלְל֥וּ יָפְיֵֽ/ךְ", "en": {"kjv": "The men of Arvad with thine army were upon thy walls round about, and the Gammadims were in thy towers: they hanged their shields upon thy walls round about; they have made thy beauty perfect.", "web": "The men of Arvad with your army were on your walls all around, and valorous men were in your towers; they hanged their shields on your walls all around; they have perfected your beauty.", "bsb": "Men of Arvad and Helech manned your walls all around, and the men of Gammad were in your towers. They hung their shields around your walls; they perfected your beauty.", "asv": "The men of Arvad with thine army were upon thy walls round about, and valorous men were in thy towers; they hanged their shields upon thy walls round about; they have perfected thy beauty.", "ylt": "The sons of Arvad, and thy force, Are on thy walls round about, And short swordsmen in thy towers have been, Their shields they have hung up on thy walls round about, They--they have perfected thy beauty.", "dra": "The men of Arad were with thy army upon thy walls round about: the Pygmeans also that were in thy towers, hung up their quivers on thy walls round about: they perfected thy beauty.", "bbe": "The men of Arvad in your army were on your walls, and were watchmen in your towers, hanging up their arms on your walls round about; they made you completely beautiful.", "geneva": "The men of Aruad with thine armie were vpon thy walles round about, and the Gammadims were in thy towres: they hanged their shields vpon thy walles round about: they haue made thy beautie perfite.", "wycliffe": "Sones Aradians with thin oost weren on thi wallis in thi cumpas; but also Pigmeis, that weren in thi touris, hangiden her arowe casis in thi wallis bi cumpas; thei filliden thi fairnesse.", "rotherham": "The sons of Arvad, :with thine army, were upon thy walls round about, And valorous in thy towers,— Their shields, hung they up on thy walls round about, They perfected thy beauty:", "darby": "The children of Arvad with thine army were upon thy walls round about, and the Gammadim were on thy towers: they hanged their shields upon thy walls round about; they made thy beauty perfect.", "twenty": "", "jps": "The men of Arvad and Helech were upon thy walls round about, and the Gammadim were in thy towers; they hanged their shields upon thy walls round about; they have perfected thy beauty.", "acv": "The men of Arvad with thine army were upon thy walls round about, and valorous men were in thy towers. They hung their shields upon thy walls round about. They have perfected thy beauty.", "anderson": "", "haweis": "", "noyes": "The men of Arvad and thine own army were upon thy walls round about, and brave warriors were in thy towers; they hung their shields upon thy walls round about; they made thy beauty perfect.", "webster": "The men of Arvad with thy army [were] upon thy walls on all sides, and the Gammadims were in thy towers: they hung their shields upon thy walls on every side; they have made thy beauty perfect.", "vulgate": "filii Aradii cum exercitu tuo erant super muros tuos in circuitu sed et Pigmei qui erant in turribus tuis faretras suas suspenderunt in muris tuis per gyrum ipsi conpleverunt pulchritudinem tuam;", "brenton": "The sons of the Aradians and thine army were upon the walls; there were guards in thy towers: they hung their quivers on thy battlements round about; these completed thy beauty."}}, {"v": 12, "ref": "27:12", "o": "תַּרְשִׁ֥ישׁ סֹחַרְתֵּ֖/ךְ מֵ/רֹ֣ב כָּל ה֑וֹן בְּ/כֶ֤סֶף בַּרְזֶל֙ בְּדִ֣יל וְ/עוֹפֶ֔רֶת נָתְנ֖וּ עִזְבוֹנָֽיִ/ךְ", "en": {"kjv": "Tarshish was thy merchant by reason of the multitude of all kind of riches; with silver, iron, tin, and lead, they traded in thy fairs.", "web": "Tarshish was your merchant by reason of the multitude of all kinds of riches; with silver, iron, tin, and lead, they traded for your wares.", "bsb": "Tarshish was your merchant because of your great wealth of goods; they exchanged silver, iron, tin, and lead for your wares.", "asv": "Tarshish was thy merchant by reason of the multitude of all kinds of riches; with silver, iron, tin, and lead, they traded for thy wares.", "ylt": "Tarshish is thy merchant, Because of the abundance of all wealth, For silver, iron, tin, and lead, They have given out thy remnants.", "dra": "The Carthaginians thy merchants supplied thy fairs with a multitude of all kinds of riches, with silver, iron, tin, and lead,", "bbe": "Tarshish did business with you because of the great amount of your wealth; they gave silver, iron, tin, and lead for your goods.", "geneva": "They of Tarshish were thy marchantes for the multitude of all riches, for siluer, yron, tynne, and leade, which they brought to thy faires.", "wycliffe": "Cartagynensis, thi marchauntis, of the multitude of alle richessis filliden thi feiris, with siluer, and irun, with tyn, and leed.", "rotherham": "Tarshish was a trader of thine. For the abundance of all wealth,— With silver iron. tin and lead, Took they part in thy traffic:", "darby": "Tarshish dealt with thee by reason of the abundance of all substance; with silver, iron, tin, and lead, they furnished thy markets.", "twenty": "", "jps": "Tarshish was thy merchant by reason of the multitude of all kinds of riches; with silver, iron, tin, and lead, they traded for thy wares.", "acv": "Tarshish was thy merchant because of the multitude of all kinds of riches, with silver, iron, tin, and lead. They traded for thy wares.", "anderson": "", "haweis": "", "noyes": "Tarshish trafficked with thee on account of the abundance of all kinds of goods; with silver, iron, tin, and lead they traded in thy fairs.", "webster": "Tarshish [was] thy merchant by reason of the multitude of all [kind of] riches; with silver, iron, tin, and lead, they traded in thy fairs.", "vulgate": "Carthaginienses negotiatores tui a multitudine cunctarum divitiarum argento ferro stagno plumboque repleverunt nundinas tuas;", "brenton": "The Carthaginians were thy merchants because of the abundance of all thy strength; they furnished thy market with silver, and gold, and iron, and tin, and lead."}}, {"v": 13, "ref": "27:13", "o": "יָוָ֤ן תֻּבַל֙ וָ/מֶ֔שֶׁךְ הֵ֖מָּה רֹֽכְלָ֑יִ/ךְ בְּ/נֶ֤פֶשׁ אָדָם֙ וּ/כְלֵ֣י נְחֹ֔שֶׁת נָתְנ֖וּ מַעֲרָבֵֽ/ךְ", "en": {"kjv": "Javan, Tubal, and Meshech, they were thy merchants: they traded the persons of men and vessels of brass in thy market.", "web": "Javan, Tubal, and Meshech, they were your traffickers; they traded the persons of men and vessels of brass for your merchandise.", "bsb": "Javan, Tubal, and Meshech were your merchants. They exchanged slaves and bronze utensils for your merchandise.", "asv": "Javan, Tubal, and Meshech, they were thy traffickers; they traded the persons of men and vessels of brass for thy merchandise.", "ylt": "Javan, Tubal, and Meshech--they are thy merchants, For persons of men, and vessels of brass, They have given out thy merchandise.", "dra": "Greece, Thubal, and Mosoch, they were thy merchants, they brought to thy people slaves and vessels of brass.", "bbe": "Javan, Tubal, and Meshech were your traders; they gave living men and brass vessels for your goods.", "geneva": "They of Iauan, Tubal and Meshech were thy marchants, concerning the liues of men, and they brought vessels of brasse for thy marchadise.", "wycliffe": "Greece, and Tubal, and Mosoch, thei weren thi marchauntis, and brouyten boonde men and brasun vessels to thi puple.", "rotherham": "Javan. Tubal and Meshech, They were merchants of thine,— With the persons of men and vessels of bronze, Shared they in thy barter:", "darby": "Javan, Tubal, and Meshech, they were thy traffickers: they bartered with thee the persons of men, and vessels of bronze.", "twenty": "", "jps": "Javan, Tubal, and Meshech, they were thy traffickers; they traded the persons of men and vessels of brass for thy merchandise.", "acv": "Javan, Tubal, and Meshech, they were thy merchants. They traded the persons of men, and vessels of brass for thy merchandise.", "anderson": "", "haweis": "", "noyes": "Javan, Tubal, and Meshech trafficked with thee; the persons of men and vessels of brass they sold in thy market.", "webster": "Javan, Tubal, and Meshech, they [were] thy merchants: they traded in the persons of men and vessels of brass in thy market.", "vulgate": "Graecia Thubal et Mosoch ipsi institores tui mancipia et vasa aerea adduxerunt populo tuo;", "brenton": "Greece, both the whole world, and the adjacent coasts, these traded with thee in the persons of men, and they gave as thy merchandise vessels of brass."}}, {"v": 14, "ref": "27:14", "o": "מִ/בֵּ֖ית תּוֹגַרְמָ֑ה סוּסִ֤ים וּ/פָֽרָשִׁים֙ וּ/פְרָדִ֔ים נָתְנ֖וּ עִזְבוֹנָֽיִ/ךְ", "en": {"kjv": "They of the house of Togarmah traded in thy fairs with horses and horsemen and mules.", "web": "They of the house of Togarmah traded for your wares with horses and war horses and mules.", "bsb": "The men of Beth-togarmah exchanged horses, war horses, and mules for your wares.", "asv": "They of the house of Togarmah traded for thy wares with horses and war-horses and mules.", "ylt": "They of the house of Togarmah, For horses, and riding steeds, and mules, They have given out thy remnants.", "dra": "From the house of Thogorma they brought horses, and horsemen, and mules to thy market.", "bbe": "The people of Togarmah gave horses and war-horses and transport beasts for your goods.", "geneva": "They of the house of Togarmah brought to thy faires horses, and horsemen, and mules.", "wycliffe": "Fro the hous of Thogorma thei brouyten horsis, and horse men, and mulis, to thi chepyng.", "rotherham": "Some of the house of Togarmah, with horses and horsemen and mules, Took part in thy traffic:", "darby": "They of the house of Togarmah furnished thy markets with horses, and horsemen, and mules.", "twenty": "", "jps": "They of the house of Togarmah traded for thy wares with horses and horsemen and mules.", "acv": "Those of the house of Togarmah traded for thy wares with horses and war-horses and mules.", "anderson": "", "haweis": "", "noyes": "They of the house of Togarmah traded in thy fairs with horses and horsemen and mules.", "webster": "They of the house of Togarmah traded in thy fairs with horses and horsemen and mules.", "vulgate": "de domo Thogorma equos et equites et mulos adduxerunt ad forum tuum;", "brenton": "Out of the house of Thogarma horses and horsemen furnished the market."}}, {"v": 15, "ref": "27:15", "o": "בְּנֵ֤י דְדָן֙ רֹֽכְלַ֔יִ/ךְ אִיִּ֥ים רַבִּ֖ים סְחֹרַ֣ת יָדֵ֑/ךְ קַרְנ֥וֹת שֵׁן֙ ו/הובנים וְ/הָבְנִ֔ים הֵשִׁ֖יבוּ אֶשְׁכָּרֵֽ/ךְ", "en": {"kjv": "The men of Dedan were thy merchants; many isles were the merchandise of thine hand: they brought thee for a present horns of ivory and ebony.", "web": "The men of Dedan were your traffickers; many islands were the market of your hand: they brought you in exchange horns of ivory and ebony.", "bsb": "The men of Dedan were your clients; many coastlands were your market; they paid you with ivory tusks and ebony.", "asv": "The men of Dedan were thy traffickers; many isles were the mart of thy hand: they brought thee in exchange horns of ivory and ebony.", "ylt": "Sons of Dedan are thy merchants, Many isles are the mart of thy hand, Horns of ivory and ebony they sent back thy reward.", "dra": "The men of Dedan were thy merchants: many islands were the traffic of thy hand, they exchanged for thy price teeth of ivory and ebony.", "bbe": "The men of Rodan were your traders: a great number of sea-lands did business with you: they gave you horns of ivory and ebony as an offering.", "geneva": "The men of Dedan were thy marchantes: and the marchandise of many yles were in thine handes: they brought thee for a present hornes, teeth, and peacockes.", "wycliffe": "The sones of Dedan weren thi marchauntis; many ilis the marchaundie of thin hond, chaungiden teeth of yuer, and of hebennus, in thi prijs.", "rotherham": "the sons of Dedan were merchants of thine, Many, isles, took the merchandise of thy hand, —Horns of ivory and ebony, gave they back to thee in exchange:", "darby": "The children of Dedan were thy traffickers; many isles were the mart of thy hand: they rendered in payment horns of ivory, and ebony.", "twenty": "", "jps": "The men of Dedan were thy traffickers; many isles were the mart of thy hand; they brought thee as tribute horns of ivory and ebony.", "acv": "The men of Dedan were thy merchants. Many isles were the mart of thy hand. They brought thee in exchange horns of ivory and ebony.", "anderson": "", "haweis": "", "noyes": "The men of Dedan trafficked with thee; many islands were at hand to thee for trade; they brought thee, for payment, horns of ivory, and ebony-wood.", "webster": "The men of Dedan [were] thy merchants; many isles [were] the merchandise of thy hand: they brought thee [for] a present horns of ivory and ebony.", "vulgate": "filii Dadan negotiatores tui insulae multae negotiatio manus tuae dentes eburneos et hebeninos commutaverunt in pretio tuo;", "brenton": "The sons of the Rhodians were thy merchants; from the islands they multiplied thy merchandise, even elephants' teeth: and to them that came in thou didst return thy prices,"}}, {"v": 16, "ref": "27:16", "o": "אֲרָ֥ם סֹחַרְתֵּ֖/ךְ מֵ/רֹ֣ב מַעֲשָׂ֑יִ/ךְ בְּ֠/נֹפֶךְ אַרְגָּמָ֨ן וְ/רִקְמָ֤ה וּ/בוּץ֙ וְ/רָאמֹ֣ת וְ/כַדְכֹּ֔ד נָתְנ֖וּ בְּ/עִזְבוֹנָֽיִ/ךְ", "en": {"kjv": "Syria was thy merchant by reason of the multitude of the wares of thy making: they occupied in thy fairs with emeralds, purple, and broidered work, and fine linen, and coral, and agate.", "web": "Syria was your merchant by reason of the multitude of your handiworks: they traded for your wares with emeralds, purple, and embroidered work, and fine linen, and coral, and rubies.", "bsb": "Aram was your customer because of your many products; they exchanged turquoise, purple, embroidered work, fine linen, coral, and rubies for your wares.", "asv": "Syria was thy merchant by reason of the multitude of thy handiworks: they traded for thy wares with emeralds, purple, and broidered work, and fine linen, and coral, and rubies.", "ylt": "Aram is thy merchant, Because of the abundance of thy works, For emerald, purple, and embroidery, And fine linen, and coral, and agate, They have given out thy remnants.", "dra": "The Syrian was thy merchant: by reason of the multitude of thy works, they set forth precious stories, and purple, and broidered works, and fine linen, and silk, and chodchod in thy market.", "bbe": "Edom did business with you because of the great number of things which you made; they gave emeralds, purple, and needlework, and the best linen and coral and rubies for your goods.", "geneva": "They of Aram were thy marchants for the multitude of thy wares: they occupied in thy faires with emerauds, purple, and broidred worke, and fine linen, and corall, and pearle.", "wycliffe": "Sirie was thi marchaunt, for the multitude of thi werkis thei settiden forth in thi marcat gemme, and purpur, and clothis wouun dyuersli at the maner of scheeldis, and bijs, and seelk, and cochod, ether auer de peis.", "rotherham": "Syria, was a trader of thine For the abundance of thy manufactures,- With carbuncle and purple and embroidery and fine linen and coral and rubies, Took they part in thy traffic:", "darby": "Syria dealt with thee for the multitude of thy handiworks: they traded in thy markets with carbuncles, purple, and broidered work, and fine linen, and corals, and rubies.", "twenty": "", "jps": "Aram was thy merchant by reason of the multitude of thy wealth; they traded for thy wares with carbuncles, purple, and richly woven work, and fine linen, and coral, and rubies.", "acv": "Syria was thy merchant because of the multitude of thy handiworks. They traded for thy wares with emeralds, purple, and embroidered work, and fine linen, and coral, and rubies.", "anderson": "", "haweis": "", "noyes": "Syria trafficked with thee by reason of the multitude of the wares of thy making; with carbuncles, purple and embroidered work, and fine linen, and corals, and rubies, they traded in thy fairs.", "webster": "Syria [was] thy merchant by reason of the multitude of the wares of thy making: they occupied in thy fairs with emeralds, purple, and broidered work, and fine linen, and coral, and agate.", "vulgate": "Syrus negotiator tuus propter multitudinem operum tuorum gemmam purpuram et scutulata et byssum et sericum et chodchod proposuerunt in mercatu tuo;", "brenton": "even men as thy merchandise, from the multitude of thy trading population, myrrh and embroidered works from Tharsis: Ramoth also and Chorchor furnished thy market."}}, {"v": 17, "ref": "27:17", "o": "יְהוּדָה֙ וְ/אֶ֣רֶץ יִשְׂרָאֵ֔ל הֵ֖מָּה רֹכְלָ֑יִ/ךְ בְּ/חִטֵּ֣י מִ֠נִּית וּ/פַנַּ֨ג וּ/דְבַ֤שׁ וָ/שֶׁ֨מֶן֙ וָ/צֹ֔רִי נָתְנ֖וּ מַעֲרָבֵֽ/ךְ", "en": {"kjv": "Judah, and the land of Israel, they were thy merchants: they traded in thy market wheat of Minnith, and Pannag, and honey, and oil, and balm.", "web": "Judah, and the land of Israel, they were your traffickers: they traded for your merchandise wheat of Minnith, and confections, and honey, and oil, and balm.", "bsb": "Judah and the land of Israel traded with you; they exchanged wheat from Minnith, cakes and honey, oil and balm for your merchandise.", "asv": "Judah, and the land of Israel, they were thy traffickers: they traded for thy merchandise wheat of Minnith, and pannag, and honey, and oil, and balm.", "ylt": "Judah and the land of Israel--they are thy merchants, For wheat of Minnith, and Pannag, And honey, and oil, and balm, They have given out thy merchandise.", "dra": "Juda and the land of Israel, they were thy merchants with the best corn: they set forth balm, and honey, and oil and rosin in thy fairs.", "bbe": "Judah and the land of Israel were your traders; they gave grain of Minnith and sweet cakes and honey and oil and perfume for your goods.", "geneva": "They of Iudah and of the land of Israel were thy marchants: they brought for thy marchandise wheat of Minnith, and Pannag, and honie and oyle, and balme.", "wycliffe": "Juda and the lond of Israel weren thi marchauntis in the beste wheete, and settiden forth in thi feiris bawme, and hony, and oile, and resyn.", "rotherham": "Judah and the land of Israel, They, were merchants of thine,— With the wheat of Minnith and the sweets of pannag and honey and oil and balsam, Shared they in thy barter:", "darby": "Judah and the land of Israel were thy traffickers: they bartered with thee wheat of Minnith, and sweet cakes, and honey, and oil, and balm.", "twenty": "", "jps": "Judah, and the land of Israel, they were thy traffickers; they traded for thy merchandise wheat of Minnith, and balsam, and honey, and oil, and balm.", "acv": "Judah, and the land of Israel, they were thy merchants. They traded for thy merchandise wheat of Minnith, and pannag, and honey, and oil, and balm.", "anderson": "", "haweis": "", "noyes": "Judah and the land of Israel trafficked with thee; with wheat of Minnith, and pastry, and syrup, and oil, and balm they traded in thy market.", "webster": "Judah, and the land of Israel, they [were] thy merchants: they traded in thy market in wheat of Minnith, and Pannag, and honey, and oil, and balm.", "vulgate": "Iuda et terra Israhel ipsi institores tui in frumento primo balsamum et mel et oleum et resinam proposuerunt in nundinis tuis;", "brenton": "Juda and the children of Israel, these were thy merchants; in the sale of corn and ointments and cassia: and they gave the best honey, and oil, and resin, to thy trading population."}}, {"v": 18, "ref": "27:18", "o": "דַּמֶּ֧שֶׂק סֹחַרְתֵּ֛/ךְ בְּ/רֹ֥ב מַעֲשַׂ֖יִ/ךְ מֵ/רֹ֣ב כָּל ה֑וֹן בְּ/יֵ֥ין חֶלְבּ֖וֹן וְ/צֶ֥מֶר צָֽחַר", "en": {"kjv": "Damascus was thy merchant in the multitude of the wares of thy making, for the multitude of all riches; in the wine of Helbon, and white wool.", "web": "Damascus was your merchant for the multitude of your handiworks, by reason of the multitude of all kinds of riches, with the wine of Helbon, and white wool.", "bsb": "Because of your many products and your great wealth of goods, Damascus traded with you wine from Helbon, wool from Zahar,", "asv": "Damascus was thy merchant for the multitude of thy handiworks, by reason of the multitude of all kinds of riches, with the wine of Helbon, and white wool.", "ylt": "Damascus is thy merchant, For the abundance of thy works, Because of the abundance of all wealth, For wine of Helbon, and white wool.", "dra": "The men of Damascus were thy merchants in the multitude of thy works, the multitude of divers riches, in rich wine, in wool of the best colour.", "bbe": "Damascus did business with you because of the great amount of your wealth, with wine of Helbon and white wool.", "geneva": "They of Damascus were thy marchants in ye multitude of thy wares, for the multitude of all riches, as in the wine of Helbon and white wooll.", "wycliffe": "Damassen was thi marchaunt, in the multitude of thi werkis, in the multitude of dyuerse richessis, in fat wyn, in wollis of best colour.", "rotherham": "Damascus was a trader of thine For the multitude of thy manufactures For the multitude of all wealth,- With the wine of Helbon and white wool:", "darby": "Damascus dealt with thee because of the multitude of thy handiworks, by reason of the abundance of all substance, with wine of Helbon, and white wool.", "twenty": "", "jps": "Damascus was thy merchant for the multitude of thy wealth, by reason of the multitude of all riches, with the wine of Helbon, and white wool.", "acv": "Damascus was thy merchant for the multitude of thy handiworks, because of the multitude of all kinds of riches, with the wine of Helbon, and white wool.", "anderson": "", "haweis": "", "noyes": "Damascus trafficked with thee on account of the multitude of the wares of thy making, on account of the abundance of all kinds of goods, in the wine of Helbon, and in white wool.", "webster": "Damascus [was] thy merchant in the multitude of the wares of thy making, for the multitude of all riches; in the wine of Helbon, and white wool.", "vulgate": "Damascenus negotiator tuus in multitudine operum tuorum in multitudine diversarum opum in vino pingui in lanis coloris optimi;", "brenton": "The people of Damascus were thy merchants by reason of the abundance of all thy power; wine out of Chelbon, and wool from Miletus; and they brought wine into thy market."}}, {"v": 19, "ref": "27:19", "o": "וְדָ֤ן וְ/יָוָן֙ מְ/אוּזָּ֔ל בְּ/עִזְבוֹנַ֖יִ/ךְ נָתָ֑נּוּ בַּרְזֶ֤ל עָשׁוֹת֙ קִדָּ֣ה וְ/קָנֶ֔ה בְּ/מַעֲרָבֵ֖/ךְ הָיָֽה", "en": {"kjv": "Dan also and Javan going to and fro occupied in thy fairs: bright iron, cassia, and calamus, were in thy market.", "web": "Vedan and Javan traded with yarn for your wares: bright iron, cassia, and calamus, were among your merchandise.", "bsb": "and casks of wine from Izal for your wares. Wrought iron, cassia, and sweet cane were exchanged for your merchandise.", "asv": "Vedan and Javan traded with yarn for thy wares: bright iron, cassia, and calamus, were among thy merchandise.", "ylt": "Vedan and Javan go about with thy remnants, They have given shining iron, cassia, and cane, In thy merchandise it hath been.", "dra": "Dan, and Greece, and Mosel have set forth in thy marts wrought iron: stacte, and calamus were in thy market.", "bbe": "... for your goods: they gave polished iron and spices for your goods.", "geneva": "They of Dan also and of Iauan, going to and from, occupied in thy faires: yron woorke, cassia and calamus were among thy marchandise.", "wycliffe": "Dan, and Greece, and Mosel, settiden forth in thi fairis irun maad suteli, gumme of myrre, and calamus, that is, a spice swete smellynge, in thi marchaundie.", "rotherham": "Wedan and Javan, from Uzal, Brought into thy traffic,— Steel, cassia and calamus, Were, in thy merchandise:", "darby": "Vedan and Javan of Uzal traded in thy markets: wrought iron, cassia, and calamus were in thy traffic.", "twenty": "", "jps": "Vedan and Javan traded with yarn for thy wares; massive iron, cassia, and calamus, were among thy merchandise.", "acv": "Vedan and Javan traded with yarn for thy wares. Bright iron, cassia, and calamus, were among thy merchandise.", "anderson": "", "haweis": "", "noyes": "Vedan and Javan brought thread to thy market; wrought iron, cassia, and sweet reed were in thy fairs.", "webster": "Dan also and Javan going to and fro occupied in thy fairs: bright iron, cassia, and calamus, were in thy market.", "vulgate": "Dan et Graecia et Mozel in nundinis tuis proposuerunt ferrum fabrefactum stacte et calamus in negotiatione tua;", "brenton": "Out of Asel came wrought iron, and there is the sound of wheels among thy trading population."}}, {"v": 20, "ref": "27:20", "o": "דְּדָן֙ רֹֽכַלְתֵּ֔/ךְ בְ/בִגְדֵי חֹ֖פֶשׁ לְ/רִכְבָּֽה", "en": {"kjv": "Dedan was thy merchant in precious clothes for chariots.", "web": "Dedan was your trafficker in precious cloths for riding.", "bsb": "Dedan was your merchant in saddlecloths for riding.", "asv": "Dedan was thy trafficker in precious cloths for riding.", "ylt": "Dedan is thy merchant, For clothes of freedom for riding.", "dra": "The men of Dedan were thy merchants in tapestry for seats.", "bbe": "Dedan did trade with you in cloths for the backs of horses.", "geneva": "They of Dedan were thy marchants in precious clothes for the charets.", "wycliffe": "Dedan weren thi marchauntis, in tapitis to sitte.", "rotherham": "Dedan was a merchant of thine,- With spreading wraps for riding:", "darby": "Dedan was thy trafficker in precious riding-cloths.", "twenty": "", "jps": "Dedan was thy trafficker in precious cloths for riding.", "acv": "Dedan was thy merchant in precious cloths for riding.", "anderson": "", "haweis": "", "noyes": "Dedan brought cloth for riding, in traffic with thee.", "webster": "Dedan [was] thy merchant in precious clothes for chariots.", "vulgate": "Dadan institores tui in tapetibus ad sedendum;", "brenton": "The people of Daedan were thy merchants, with choice cattle for chariots."}}, {"v": 21, "ref": "27:21", "o": "עֲרַב֙ וְ/כָל נְשִׂיאֵ֣י קֵדָ֔ר הֵ֖מָּה סֹחֲרֵ֣י יָדֵ֑/ךְ בְּ/כָרִ֤ים וְ/אֵילִים֙ וְ/עַתּוּדִ֔ים בָּ֖/ם סֹחֲרָֽיִ/ךְ", "en": {"kjv": "Arabia, and all the princes of Kedar, they occupied with thee in lambs, and rams, and goats: in these were they thy merchants.", "web": "Arabia, and all the princes of Kedar, they were the merchants of your hand; in lambs, and rams, and goats, in these were they your merchants.", "bsb": "Arabia and all the princes of Kedar were your customers, trading in lambs, rams, and goats.", "asv": "Arabia, and all the princes of Kedar, they were the merchants of thy hand; in lambs, and rams, and goats, in these were they thy merchants.", "ylt": "Arabia, and all princes of Kedar, They are the traders of thy hand, For lambs, and rams, and he-goats, In these thy merchants.", "dra": "Arabia, and all the princes of Cedar, they were the merchants of thy hand: thy merchants came to thee with lambs, and rams, and kids.", "bbe": "Arabia and all the rulers of Kedar did business with you; in lambs and sheep and goats, in these they did business with you.", "geneva": "They of Arabia, and all the princes of Kedar occupied with thee, in lambes, and rammes and goates: in these were they thy marchants.", "wycliffe": "Arabie and alle the princes of Cedar, thei weren the marchauntis of thin hond; with lambren, and wetheris, and kidis thi marchauntis camen to thee.", "rotherham": "Arabia and all the princes of Kedar, They, were traders at thy service,— With lambs and rams and he-goats, With these, were they traders of thine:", "darby": "Arabia and all the princes of Kedar were the merchants of thy hand: in lambs, and rams, and goats, in these did they trade with thee.", "twenty": "", "jps": "Arabia, and all the princes of Kedar, they were the merchants of thy hand; in lambs, and rams, and goats, in these were they thy merchants.", "acv": "Arabia, and all the rulers of Kedar, they were the merchants of thy hand, in lambs, and rams, and goats. In these they were thy merchants.", "anderson": "", "haweis": "", "noyes": "Arabia and all the princes of Kedar were at hand to traffic with thee; they traded with thee in lambs and rams and goats.", "webster": "Arabia, and all the princes of Kedar, they occupied with thee in lambs, and rams, and goats: in these [were they] thy merchants.", "vulgate": "Arabia et universi principes Cedar ipsi negotiatores manus tuae cum agnis et arietibus et hedis venerunt ad te negotiatores tui;", "brenton": "Arabia and all the princes of Kedar, these were thy traders with thee, bringing camels, and lambs, and rams, in which they trade with thee."}}, {"v": 22, "ref": "27:22", "o": "רֹכְלֵ֤י שְׁבָא֙ וְ/רַעְמָ֔ה הֵ֖מָּה רֹכְלָ֑יִ/ךְ בְּ/רֹ֨אשׁ כָּל בֹּ֜שֶׂם וּ/בְ/כָל אֶ֤בֶן יְקָרָה֙ וְ/זָהָ֔ב נָתְנ֖וּ עִזְבוֹנָֽיִ/ךְ", "en": {"kjv": "The merchants of Sheba and Raamah, they were thy merchants: they occupied in thy fairs with chief of all spices, and with all precious stones, and gold.", "web": "The traffickers of Sheba and Raamah, they were your traffickers; they traded for your wares with the chief of all spices, and with all precious stones, and gold.", "bsb": "The merchants of Sheba and Raamah traded with you; for your wares they exchanged gold, the finest of all spices, and precious stones.", "asv": "The traffickers of Sheba and Raamah, they were thy traffickers; they traded for thy wares with the chief of all spices, and with all precious stones, and gold.", "ylt": "Merchants of Sheba and Raamah--they are thy merchants, For the chief of all spices, And for every precious stone, and gold, They have given out thy remnants.", "dra": "The sellers of Saba, and Reema, they were thy merchants: with all the best spices, and precious stones, and gold, which they set forth in thy market.", "bbe": "The traders of Sheba and Raamah did trade with you; they gave the best of all sorts of spices and all sorts of stones of great price and gold for your goods.", "geneva": "The marchats of Sheba, and Raamah were thy marchantes: they occupied in thy faires with the chiefe of all spices, and with al precious stones and golde.", "wycliffe": "The silleris of Saba and of Rema, thei weren thi marchauntis, with alle the beste swete smellynge spices, and preciouse stoon, and gold, which thei settiden forth in thi marcat.", "rotherham": "The merchants of Sheba and Raamah, They were merchants of thine,— With the chief of all spices and with every kind of precious stone and gold, Took they part in thy traffic:", "darby": "The merchants of Sheba and Raamah were thy traffickers: they furnished thy markets with all the choice spices, and with all precious stones and gold.", "twenty": "", "jps": "The traffickers of Sheba and Raamah, they were thy traffickers; they traded for thy wares with chief of all spices, and with all precious stones, and gold.", "acv": "The merchants of Sheba and Raamah, they were thy merchants. They traded for thy wares with the chief of all spices, and with all precious stones, and gold.", "anderson": "", "haweis": "", "noyes": "The merchants of Sheba and Raamah trafficked with thee with all kinds of precious spices, and with all kinds of precious stones, and gold.", "webster": "The merchants of Sheba and Raamah, they [were] thy merchants: they occupied in thy fairs with chief of all spices, and with all precious stones, and gold.", "vulgate": "venditores Saba et Reema ipsi negotiatores tui cum universis primis aromatibus et lapide pretioso et auro quod proposuerunt in mercatu tuo;", "brenton": "The merchants of Sabba and Ramma, these were thy merchants, with choice spices, and precious stones: and they brought gold to thy market."}}, {"v": 23, "ref": "27:23", "o": "חָרָ֤ן וְ/כַנֵּה֙ וָ/עֶ֔דֶן רֹכְלֵ֖י שְׁבָ֑א אַשּׁ֖וּר כִּלְמַ֥ד רֹכַלְתֵּֽ/ךְ", "en": {"kjv": "Haran, and Canneh, and Eden, the merchants of Sheba, Asshur, and Chilmad, were thy merchants.", "web": "Haran and Canneh and Eden, the traffickers of Sheba, Asshur and Chilmad, were your traffickers.", "bsb": "Haran, Canneh, and Eden traded with you, and so did the merchants of Sheba, Asshur, and Chilmad.", "asv": "Haran and Canneh and Eden, the traffickers of Sheba, Asshur and Chilmad, were thy traffickers.", "ylt": "Haran, and Canneh, and Eden, merchants of Sheba, Asshur--Chilmad-- are thy merchants,", "dra": "Haran, and Chene, and Eden were thy merchants; Saba, Assur, and Chelmad sold to thee.", "bbe": "Haran and Canneh and Eden, the traders of Asshur and all the Medes:", "geneva": "They of Haram and Canneh and Eden, the marchants of Sheba, Asshur and Chilmad were thy marchants.", "wycliffe": "Aran, and Chenne, and Eden, weren thi marchauntis; Sabba, and Assur, and Chelmath, weren thi silleris.", "rotherham": "Haran and Canneh and Eden, the merchants of Sheba,—Asshur. Chilmad, Were merchants of thine:", "darby": "Haran, and Canneh, and Eden, the merchants of Sheba, Asshur, and Chilmad traded with thee:", "twenty": "", "jps": "Haran and Canneh and Eden, the traffickers of Sheba, Asshur was as thine apprentice in traffic.", "acv": "Haran and Canneh and Eden, the merchants of Sheba, Asshur and Chilmad, were thy merchants.", "anderson": "", "haweis": "", "noyes": "Haran, and Canneh, and Eden, the merchants of Sheba, Assyria, and Chilmad,", "webster": "Haran, and Canneh, and Eden, the merchants of Sheba, Asshur, [and] Chilmad, [were] thy merchants.", "vulgate": "Aran et Chenne et Eden negotiatores Saba Assur Chelmad venditores tui;", "brenton": "Charra, and Chanaa, these were thy merchants: Assur, and Charman, were thy merchants:"}}, {"v": 24, "ref": "27:24", "o": "הֵ֤מָּה רֹכְלַ֨יִ/ךְ֙ בְּ/מַכְלֻלִ֔ים בִּ/גְלוֹמֵי֙ תְּכֵ֣לֶת וְ/רִקְמָ֔ה וּ/בְ/גִנְזֵ֖י בְּרֹמִ֑ים בַּ/חֲבָלִ֧ים חֲבֻשִׁ֛ים וַ/אֲרֻזִ֖ים בְּ/מַרְכֻלְתֵּֽ/ךְ", "en": {"kjv": "These were thy merchants in all sorts of things, in blue clothes, and broidered work, and in chests of rich apparel, bound with cords, and made of cedar, among thy merchandise.", "web": "These were your traffickers in choice wares, in wrappings of blue and embroidered work, and in chests of rich clothing, bound with cords and made of cedar, among your merchandise.", "bsb": "In your marketplace they traded with you fine garments of blue, embroidered work, and multicolored rugs with cords tightly twisted and knotted.", "asv": "These were thy traffickers in choice wares, in wrappings of blue and broidered work, and in chests of rich apparel, bound with cords and made of cedar, among thy merchandise.", "ylt": "They are thy merchants for perfect things, For wrappings of blue, and embroidery, And for treasuries of rich apparel, With cords bound and girded, for thy merchandise,", "dra": "They were thy merchants in divers manners, with bales of blue cloth, and of embroidered work, and of precious riches, which were wrapped up and bound with cords: they had cedars also in thy merchandise.", "bbe": "These were your traders in beautiful robes, in rolls of blue and needlework, and in chests of coloured cloth, corded with cords and made of cedar-wood, in them they did trade with you.", "geneva": "These were thy marchants in all sortes of things, in raiment of blewe silke, and of broydred woorke, and in coffers for the rich apparell, which were bound with cordes: chaines also were among thy marchandise.", "wycliffe": "Thei weren thi marchaundis in many maneres, in fardels of iacinct and of clothis of many colours, and of preciouse richessis, that weren wlappid and boundun with coordis.", "rotherham": "Those were thy merchants for gorgeous garments, for wrappings of blue and embroidery, and for treasure-chests of variegated cloth,—for cords, twisted and strong, in thy market:", "darby": "these traded with thee in sumptuous clothes, in wrappings of blue and broidered work, and in chests full of variegated stuffs, bound with cords and made of cedar-wood, amongst thy merchandise.", "twenty": "", "jps": "These were thy traffickers in gorgeous fabrics, in wrappings of blue and richly woven work, and in chests of rich apparel, bound with cords and cedar-lined, among thy merchandise.", "acv": "These were thy merchants in choice wares, in wrappings of blue and embroidered work, and in chests of rich apparel, bound with cords and made of cedar, among thy merchandise.", "anderson": "", "haweis": "", "noyes": "trafficked with thee in splendid apparel, in mantles of blue and embroidered work, in chests of damask bound with cords and made of cedar, in thy market.", "webster": "These [were] thy merchants in all sorts [of things], in blue clothes, and broidered work, and in chests of rich apparel, bound with cords, and made of cedar, among thy merchandise.", "vulgate": "ipsi negotiatores tui multifariam involucris hyacinthi et polymitorum gazarumque pretiosarum quae obvolutae et adstrictae erant funibus cedros quoque habebant in negotiationibus tuis;", "brenton": "bringing for merchandise blue, and choice stores bound with cords, and cypress wood."}}, {"v": 25, "ref": "27:25", "o": "אֳנִיּ֣וֹת תַּרְשִׁ֔ישׁ שָׁרוֹתַ֖יִ/ךְ מַעֲרָבֵ֑/ךְ וַ/תִּמָּלְאִ֧י וַֽ/תִּכְבְּדִ֛י מְאֹ֖ד בְּ/לֵ֥ב יַמִּֽים", "en": {"kjv": "The ships of Tarshish did sing of thee in thy market: and thou wast replenished, and made very glorious in the midst of the seas.", "web": "The ships of Tarshish were your caravans for your merchandise: and you were replenished, and made very glorious in the heart of the seas.", "bsb": "The ships of Tarshish carried your merchandise. And you were filled with heavy cargo in the heart of the sea.", "asv": "The ships of Tarshish were thy caravans for thy merchandise: and thou wast replenished, and made very glorious in the heart of the seas.", "ylt": "Ships of Tarshish are thy double walls of thy merchandise, And thou art filled and honoured greatly, In the heart of the seas.", "dra": "The ships of the sea, were thy chief in thy merchandise: and thou wast replenished, and glorified exceedingly in the heart of the sea.", "bbe": "Tarshish ships did business for you in your goods: and you were made full, and great was your glory in the heart of the seas.", "geneva": "The shippes of Tarshish were thy chiefe in thy marchandise, and thou wast replenished and made very glorious in the middes of the sea.", "wycliffe": "Also schippis of the see hadden cedris in her marchaundies; thi princes weren in thi marchaundie; and thou were fillid, and were glorified greetli in the herte of the see.", "rotherham": "the ships of Tarshish, were thy masts Carrying on thy barter, So wast thou filled and becamest very glorious In the heart of the seas.", "darby": "The ships of Tarshish were thy caravans for thy traffic; and thou wast replenished, and highly honoured, in the heart of the seas.", "twenty": "", "jps": "The ships of Tarshish brought thee tribute for thy merchandise; so wast thou replenished, and made very heavy in the heart of the seas.", "acv": "The ships of Tarshish were thy caravans for thy merchandise. And thou were replenished, and made very glorious in the heart of the seas.", "anderson": "", "haweis": "", "noyes": "The ships of Tarshish were the caravans for thy traffic; and thou wast replenished and made very glorious in the midst of the seas.", "webster": "The ships of Tarshish did sing of thee in thy market; and thou wast replenished, and made very glorious in the midst of the seas.", "vulgate": "naves maris principes tuae in negotiatione tua et repleta es et glorificata nimis in corde maris;", "brenton": "Ships were thy merchants, in abundance, with thy trading population: and thou wast filled and very heavily loaded in the heart of the sea."}}, {"v": 26, "ref": "27:26", "o": "בְּ/מַ֤יִם רַבִּים֙ הֱבִיא֔וּ/ךְ הַ/שָּׁטִ֖ים אֹתָ֑/ךְ ר֚וּחַ הַ/קָּדִ֔ים שְׁבָרֵ֖/ךְ בְּ/לֵ֥ב יַמִּֽים", "en": {"kjv": "Thy rowers have brought thee into great waters: the east wind hath broken thee in the midst of the seas.", "web": "Your rowers have brought you into great waters: the east wind has broken you in the heart of the seas.", "bsb": "Your oarsmen have brought you onto the high seas, but the east wind will shatter you in the heart of the sea.", "asv": "Thy rowers have brought thee into great waters: the east wind hath broken thee in the heart of the seas.", "ylt": "Into great waters have they brought thee, Those rowing thee, The east wind hath broken thee in the heart of the seas.", "dra": "Thy rowers have brought thee into great waters: the south wind hath broken thee in the heart of the sea.", "bbe": "Your boatmen have taken you into great waters: you have been broken by the east wind in the heart of the seas.", "geneva": "Thy robbers haue brought thee into great waters: the East winde hath broken thee in the middes of the sea.", "wycliffe": "Thi rowers brouyten thee in many watris, the south wynd al to-brak thee; in the herte of the see weren thi richessis,", "rotherham": "Into mighty waters, have they brought thee, the rowers—even thee,— the east wind, hath broken thee In the heart of the seas:", "darby": "Thy rowers have brought thee into great waters; the east wind hath broken thee in the heart of the seas.", "twenty": "", "jps": "Thy rowers have brought thee into great waters; the east wind hath broken thee in the heart of the seas.", "acv": "Thy rowers have brought thee into great waters. The east wind has broken thee in the heart of the seas.", "anderson": "", "haweis": "", "noyes": "Thy rowers have brought thee into great waters; the east wind hath broken thee in the midst of the seas.", "webster": "Thy rowers have brought thee into great waters: the east wind hath broken thee in the midst of the seas.", "vulgate": "in aquis multis adduxerunt te remiges tui ventus auster contrivit te in corde maris;", "brenton": "Thy rowers have brought thee into great waters: the south wind has broken thee in the heart of the sea."}}, {"v": 27, "ref": "27:27", "o": "הוֹנֵ/ךְ֙ וְ/עִזְבוֹנַ֔יִ/ךְ מַעֲרָבֵ֕/ךְ מַלָּחַ֖יִ/ךְ וְ/חֹבְלָ֑יִ/ךְ מַחֲזִיקֵ֣י בִדְקֵ֣/ך וְֽ/עֹרְבֵ֣י מַ֠עֲרָבֵ/ךְ וְ/כָל אַנְשֵׁ֨י מִלְחַמְתֵּ֜/ךְ אֲשֶׁר בָּ֗/ךְ וּ/בְ/כָל קְהָלֵ/ךְ֙ אֲשֶׁ֣ר בְּ/תוֹכֵ֔/ךְ יִפְּלוּ֙ בְּ/לֵ֣ב יַמִּ֔ים בְּ/י֖וֹם מַפַּלְתֵּֽ/ךְ", "en": {"kjv": "Thy riches, and thy fairs, thy merchandise, thy mariners, and thy pilots, thy calkers, and the occupiers of thy merchandise, and all thy men of war, that are in thee, and in all thy company which is in the midst of thee, shall fall into the midst of the seas in the day of thy ruin.", "web": "Your riches, and your wares, your merchandise, your mariners, and your pilots, your repairers of ship seams, and the dealers in your merchandise, and all your men of war, who are in you, with all your company which is in your midst, shall fall into the heart of the seas in the day of your ruin.", "bsb": "Your wealth, wares, and merchandise, your sailors, captains, and shipwrights, your merchants and all the warriors within you, with all the other people on board, will sink into the heart of the sea on the day of your downfall.", "asv": "Thy riches, and thy wares, thy merchandise, thy mariners, and thy pilots, thy calkers, and the dealers in thy merchandise, and all thy men of war, that are in thee, with all thy company which is in the midst of thee, shall fall into the heart of the seas in the day of thy ruin.", "ylt": "Thy wealth and thy remnants, Thy merchandise, thy mariners, And thy pilots, strengtheners of thy breach, And the traders of thy merchandise, And all thy men of war, who are in thee, And in all thine assembly that is in thy midst, Fall into the heart of the seas in the day of thy fall,", "dra": "Thy riches, and thy treasures, and thy manifold furniture, thy mariners, and thy pilots, who kept thy goods, and were chief over thy people: thy men of war also, that were in thee, with all thy multitude that is in the midst of thee: shall fall in the heart of the sea in the day of thy ruin.", "bbe": "Your wealth and your goods, the things in which you do trade, your seamen and those guiding your ships, those who make your boards watertight, and those who do business with your goods, and all your men of war who are in you, with all who have come together in you, will go down into the heart of the seas in the day of your downfall.", "geneva": "Thy riches and thy faires, thy marchandise, thy mariners and pilotes, thy calkers, and the occupiers of thy marchandise and al thy men of warre that are in thee, and all thy multitude which is in the middes of thee, shall fall in the middes of the sea in the day of thy ruine.", "wycliffe": "and thi tresours, and thi many fold instrument. Thi schip men, and thi gouernouris that helden thi purtenaunce of houshold, and weren souereyns of thi puple, and thi men werriours that weren in thee, with al thi multitude which is in the myddis of thee, schulen falle doun in the herte of the see, in the dai of thi fallyng.", "rotherham": "Thy wealth and thy wares, thy merchandise thy mariners, and thy sailors,-thy calkers and the barterers of thy merchandise and all thy men of war who are in thee and in all thy gathered host which is in thy midst Shall fall into the heart of the seas, In the day of thy fall.", "darby": "Thy substance, and thy markets, thy merchandise, thy mariners, and thy pilots, they that repair thy leaks, and they that barter with thee, and all thy men of war that are in thee, along with all thine assemblage which is in the midst of thee, shall fall into the heart of the seas in the day of thy fall.", "twenty": "", "jps": "Thy riches, and thy wares, thy merchandise, thy mariners, and thy pilots, thy calkers, and the exchangers of thy merchandise, and all thy men of war, that are in thee, with all thy company which is in the midst of thee, shall fall into the heart of the seas in the day of thy ruin.", "acv": "Thy riches, and thy wares, thy merchandise, thy mariners, and thy pilots, thy caulkers, and the dealers in thy merchandise, and all thy men of war, who are in thee, with all thy company which is in the midst of thee, shall fall into the heart of the seas in the day of thy ruin.", "anderson": "", "haweis": "", "noyes": "Thy riches, and thy fairs, and thy merchandise, thy mariners, and thy pilots, thy calkers, and the traders in thy merchandise, and all thy men of war within thee, and all thy multitude that is in the midst of thee, shall fall into the midst of the seas in the day of thy ruin.", "webster": "Thy riches, and thy fairs, thy merchandise, thy mariners, and thy pilots, thy calkers, and the occupiers of thy merchandise, and all thy military men, that [are] in thee, and in all thy company which [is] in the midst of thee, shall fall into the midst of the seas in the day of thy ruin.", "vulgate": "divitiae tuae et thesauri tui et multiplex instrumentum tuum nautae tui et gubernatores tui qui tenebant supellectilem tuam et populo tuo praeerant viri quoque bellatores tui qui erant in te cum universa multitudine tua quae est in medio tui cadent in corde maris in die ruinae tuae;", "brenton": "Thy forces, and thy gain, and that of thy traders, and thy rowers, and thy pilots, and thy counselors, and they that traffic with thee, and all thy warriors that are in thee: and all thy company in the midst of thee shall perish in the heart of the sea, in the day of thy fall."}}, {"v": 28, "ref": "27:28", "o": "לְ/ק֖וֹל זַעֲקַ֣ת חֹבְלָ֑יִ/ךְ יִרְעֲשׁ֖וּ מִגְרֹשֽׁוֹת", "en": {"kjv": "The suburbs shall shake at the sound of the cry of thy pilots.", "web": "At the sound of the cry of your pilots the suburbs shall shake.", "bsb": "The countryside will shake when your sailors cry out.", "asv": "At the sound of the cry of thy pilots the suburbs shall shake.", "ylt": "At the voice of the cry of thy pilots shake do the suburbs.", "dra": "Thy fleets shall be troubled at the sound of the cry of thy pilots.", "bbe": "At the sound of the cry of your ships' guides, the boards of the ship will be shaking.", "geneva": "The suburbes shall shake at the sound of the crie of thy pilotes.", "wycliffe": "Schippis schulen be disturblid of the sown of the cry of thi gouernours;", "rotherham": "At the sound of the outcry of thy pilots, the coasts shall quake:", "darby": "The open places shall shake at the sound of the cry of thy pilots.", "twenty": "", "jps": "At the sound of the cry of thy pilots the waves shall shake.", "acv": "At the sound of the cry of thy pilots the suburbs shall shake.", "anderson": "", "haweis": "", "noyes": "At the sound of the cry of thy pilots the pastures around thee shall shake.", "webster": "The suburbs shall shake at the sound of the cry of thy pilots.", "vulgate": "a sonitu clamoris gubernatorum tuorum conturbabuntur classes;", "brenton": "At the cry of thy voice thy pilots shall be greatly terrified."}}, {"v": 29, "ref": "27:29", "o": "וְֽ/יָרְד֞וּ מֵ/אָנִיּֽוֹתֵי/הֶ֗ם כֹּ֚ל תֹּפְשֵׂ֣י מָשׁ֔וֹט מַלָּחִ֕ים כֹּ֖ל חֹבְלֵ֣י הַ/יָּ֑ם אֶל הָ/אָ֖רֶץ יַעֲמֹֽדוּ", "en": {"kjv": "And all that handle the oar, the mariners, and all the pilots of the sea, shall come down from their ships, they shall stand upon the land;", "web": "All who handled the oar, the mariners, and all the pilots of the sea, shall come down from their ships; they shall stand on the land,", "bsb": "All who handle the oars will abandon their ships. The sailors and all the captains of the sea will stand on the shore.", "asv": "And all that handle the oar, the mariners, and all the pilots of the sea, shall come down from their ships; they shall stand upon the land,", "ylt": "And come down from their ships have all handling an oar, Mariners, all the pilots of the sea, on the land they stand,", "dra": "And all that handled the oar shall come down from their ships: the mariners, and all the pilots of the sea shall stand upon the land:", "bbe": "And all the boatmen, the seamen and those who are expert at guiding a ship through the sea, will come down from their ships and take their places on the land;", "geneva": "And all that handle the ore, the mariners and al the pilots of the sea shall come downe from their shippes, and shall stand vpon the land,", "wycliffe": "and alle men that helden oore, schulen go doun of her shippis. Shipmen and alle gouernouris of the see shulen stonde in the lond;", "rotherham": "Then shall come down from their ships all that handle the oar, mariners, all the sailors of the sea— Upon the land, shall they take up their station;", "darby": "And all that handle the oar, the mariners, all the pilots of the sea, shall come down from their ships; they shall stand upon the land,", "twenty": "", "jps": "And all that handle the oar, the mariners, and all the pilots of the sea, shall come down from their ships, they shall stand upon the land,", "acv": "And all who handled the oar, the mariners, and all the pilots of the sea, shall come down from their ships. They shall stand upon the land,", "anderson": "", "haweis": "", "noyes": "And all that handle the oar, the mariners, and all the pilots of the sea, shall come down from their ships; they shall stand upon the land,", "webster": "And all that handle the oar, the mariners, [and] all the pilots of the sea, shall come down from their ships, they shall stand upon the land;", "vulgate": "et descendent de navibus suis omnes qui tenebant remum nautae et universi gubernatores maris in terra stabunt;", "brenton": "And all the rowers and the mariners shall come down from the ships, and the pilots of the sea shall stand on the land."}}, {"v": 30, "ref": "27:30", "o": "וְ/הִשְׁמִ֤יעוּ עָלַ֨יִ/ךְ֙ בְּ/קוֹלָ֔/ם וְ/יִזְעֲק֖וּ מָרָ֑ה וְ/יַעֲל֤וּ עָֽפָר֙ עַל רָ֣אשֵׁי/הֶ֔ם בָּ/אֵ֖פֶר יִתְפַּלָּֽשׁוּ", "en": {"kjv": "And shall cause their voice to be heard against thee, and shall cry bitterly, and shall cast up dust upon their heads, they shall wallow themselves in the ashes:", "web": "and shall cause their voice to be heard over you, and shall cry bitterly, and shall cast up dust on their heads, they shall wallow themselves in the ashes:", "bsb": "They will raise their voices for you and cry out bitterly. They will throw dust on their heads and roll in ashes.", "asv": "and shall cause their voice to be heard over thee, and shall cry bitterly, and shall cast up dust upon their heads; they shall wallow themselves in the ashes:", "ylt": "And have sounded for thee with their voice, And cry bitterly, and cause dust to go up on their heads, In ashes they do roll themselves.", "dra": "And they shall mourn over thee with a loud voice and shall cry bitterly: and they shall cast up dust upon their heads and shall be sprinkled with ashes.", "bbe": "And their voices will be sounding over you, and crying bitterly they will put dust on their heads, rolling themselves in the dust:", "geneva": "And shall cause their voyce to be heard against thee, and shall cry bitterly, and shall cast dust vpon their heads, and wallow theselues in the ashes.", "wycliffe": "and schulen yelle on thee with greet vois. And thei shulen cry bitterli, and thei schulen caste poudur on her heedis, and schulen be spreynt with aische.", "rotherham": "And make loud [lament] over thee, with their voice, And make biter outcry,- And shall lift up dust on their heads, In ashes, shall roll themselves;", "darby": "and shall cause their voice to be heard over thee, and shall cry bitterly; and they shall cast up dust upon their heads; they shall wallow themselves in ashes.", "twenty": "", "jps": "And shall cause their voice to be heard over thee, and shall cry bitterly, and shall cast up dust upon their heads, they shall roll themselves in the ashes;", "acv": "and shall cause their voice to be heard over thee, and shall cry bitterly, and shall cast up dust upon their heads. They shall wallow themselves in the ashes.", "anderson": "", "haweis": "", "noyes": "and shall cause their voice to be heard for thee, and shall cry bitterly, and shall cast dust upon their heads, and roll themselves in ashes.", "webster": "And shall cause their voice to be heard against thee, and shall cry bitterly, and shall cast up dust upon their heads, they shall wallow themselves in the ashes:", "vulgate": "et heiulabunt super te voce magna et clamabunt amare et superiacient pulverem capitibus suis et cinere conspergentur;", "brenton": "And they shall wail over thee with their voice, and cry bitterly, and put earth on their heads, and spread ashes under them."}}, {"v": 31, "ref": "27:31", "o": "וְ/הִקְרִ֤יחוּ אֵלַ֨יִ/ךְ֙ קָרְחָ֔ה וְ/חָגְר֖וּ שַׂקִּ֑ים וּ/בָכ֥וּ אֵלַ֛יִ/ךְ בְּ/מַר נֶ֖פֶשׁ מִסְפֵּ֥ד מָֽר", "en": {"kjv": "And they shall make themselves utterly bald for thee, and gird them with sackcloth, and they shall weep for thee with bitterness of heart and bitter wailing.", "web": "and they shall make themselves bald for you, and clothe them with sackcloth, and they shall weep for you in bitterness of soul with bitter mourning.", "bsb": "They will shave their heads for you and wrap themselves in sackcloth. They will weep over you with anguish of soul and bitter mourning.", "asv": "and they shall make themselves bald for thee, and gird them with sackcloth, and they shall weep for thee in bitterness of soul with bitter mourning.", "ylt": "And they have made for thee baldness, And they have girded on sackcloth, And they have wept for thee, In bitterness of soul--a bitter mourning.", "dra": "And they shall shave themselves bald for thee, and shall be girded with haircloth: and they shall weep for thee with bitterness of soul, with most bitter weeping.", "bbe": "And they will have the hair of their heads cut off because of you, and will put haircloth on their bodies, weeping for you with bitter grief in their souls, even with bitter sorrow.", "geneva": "They shall plucke off their heare for thee and gird them with a sackecloth, and they shall weepe for thee with sorow of heart and bitter mourning.", "wycliffe": "And thei schulen shaue ballidnesse on thee, and schulen be gird with hairis, and thei schulen biwepe thee in bitternesse of soule, with most bittir wepyng.", "rotherham": "And shall make bald for thee a baldness And gird them with sackcloth,— And shall weep for thee in bitterness of soul A bitter lamentation;", "darby": "And they shall make themselves utterly bald for thee, and gird themselves with sackcloth; and they shall weep for thee in bitterness of soul with bitter mourning.", "twenty": "", "jps": "And they shall make themselves utterly bald for thee, and gird them with sackcloth, and they shall weep for thee in bitterness of soul with bitter lamentation.", "acv": "And they shall make themselves bald for thee, and gird with sackcloth, and they shall weep for thee in bitterness of soul with bitter mourning.", "anderson": "", "haweis": "", "noyes": "And they shall make themselves utterly bald for thee, and gird themselves with sackcloth; and they shall weep for thee with bitterness of heart and bitter wailing.", "webster": "And they shall make themselves utterly bald for thee, and gird themselves with sackcloth, and they shall weep for thee with bitterness of heart [and] bitter wailing.", "vulgate": "et radent super te calvitium et accingentur ciliciis et plorabunt te in amaritudine animae ploratu amarissimo;", "brenton": ""}}, {"v": 32, "ref": "27:32", "o": "וְ/נָשְׂא֨וּ אֵלַ֤יִ/ךְ בְּ/נִי/הֶם֙ קִינָ֔ה וְ/קוֹנְנ֖וּ עָלָ֑יִ/ךְ מִ֣י כְ/צ֔וֹר כְּ/דֻמָ֖ה בְּ/ת֥וֹךְ הַ/יָּֽם", "en": {"kjv": "And in their wailing they shall take up a lamentation for thee, and lament over thee, saying, What city is like Tyrus, like the destroyed in the midst of the sea?", "web": "In their wailing they shall take up a lamentation for you, and lament over you, saying, Who is there like Tyre, like her who is brought to silence in the midst of the sea?", "bsb": "As they wail and mourn over you, they will take up a lament for you: ‘Who was ever like Tyre, silenced in the middle of the sea?", "asv": "And in their wailing they shall take up a lamentation for thee, and lament over thee, saying, Who is there like Tyre, like her that is brought to silence in the midst of the sea?", "ylt": "And lifted up for thee have their sons a lamentation, And they have lamented over thee, who is as Tyre? As the cut-off one in the midst of the sea?", "dra": "And they shall take up a mournful song for thee, and shall lament thee: What city is like Tyre, which is become silent in the midst of the sea?", "bbe": "And in their weeping they will make a song of grief for you, sorrowing over you and saying, Who is like Tyre, who has come to an end in the deep sea?", "geneva": "And in their mourning, they shall take vp a lametation for thee, saying, What citie is like Tyrus, so destroied in the middes of the sea!", "wycliffe": "And thei schulen take on thee a song of mourenyng, and thei schulen biweile thee, Who is as Tire, that was doumb in the myddis of the see?", "rotherham": "And shall take up for thee in their Wailing: a dirge, And shall chant over thee,- Who is like Tyre? Like the Sent One in the midst of the sea?", "darby": "And in their wailing they shall take up a lamentation for thee, and lament over thee, [saying,] Who is like Tyre, like her that is destroyed in the midst of the sea?", "twenty": "", "jps": "And in their wailing they shall take up a lamentation for thee, and lament over thee: who was there like Tyre, fortified in the midst of the sea?", "acv": "And in their wailing they shall take up a lamentation for thee, and lament over thee, saying, Who is there like Tyre, like her that is brought to silence in the midst of the sea?", "anderson": "", "haweis": "", "noyes": "And in their wailing they shall take up for thee a lamentation, and shall lament over thee, saying: \"What city is like Tyre, like the Destroyed in the midst of the sea?", "webster": "And in their wailing they shall take up a lamentation for thee, and lament over thee, [saying], What [city is] like Tyre, like the destroyed in the midst of the sea?", "vulgate": "et adsument super te carmen lugubre et plangent te quae est ut Tyrus quae obmutuit in medio maris;", "brenton": "And their sons shall take up a lament for thee, even a lamentation for Sor, saying,"}}, {"v": 33, "ref": "27:33", "o": "בְּ/צֵ֤את עִזְבוֹנַ֨יִ/ךְ֙ מִ/יַּמִּ֔ים הִשְׂבַּ֖עַתְּ עַמִּ֣ים רַבִּ֑ים בְּ/רֹ֤ב הוֹנַ֨יִ/ךְ֙ וּ/מַ֣עֲרָבַ֔יִ/ךְ הֶעֱשַׁ֖רְתְּ מַלְכֵי אָֽרֶץ", "en": {"kjv": "When thy wares went forth out of the seas, thou filledst many people; thou didst enrich the kings of the earth with the multitude of thy riches and of thy merchandise.", "web": "When your wares went out of the seas, you filled many peoples; you enriched the kings of the earth with the multitude of your riches and of your merchandise.", "bsb": "When your wares went out to sea, you satisfied many nations. You enriched the kings of the earth with your abundant wealth and merchandise.", "asv": "When thy wares went forth out of the seas, thou filledst many peoples; thou didst enrich the kings of the earth with the multitude of thy riches and of thy merchandise.", "ylt": "With the outgoing of thy remnants from the seas, Thou hast filled many peoples, With the abundance of thy riches, and thy merchandise, Thou hast made rich things of earth.", "dra": "Which by thy merchandise that went from thee by sea didst fill many people: which by the multitude of thy riches, and of thy people didst enrich the kings of the earth.", "bbe": "When your goods went out over the seas, you made numbers of peoples full; the wealth of the kings of the earth was increased with your great wealth and all your goods.", "geneva": "When thy wares went foorth of the seas, thou filledst many people, and thou diddest enrich the Kings of the earth with the multitude of thy riches and of thy marchandise.", "wycliffe": "And thou, Tire, fillidist many puplis in the goyng out of thi marchaundies of the see; in the multitude of thi richessis, and of thi puplis, thou madist riche the kingis of erthe.", "rotherham": "By the going forth of thy commodities out of the seas, Thou didst satisfy many peoples, By the multitude of thy wares and of thy merchandise, Thou didst enrich the kings of the earth.", "darby": "When thy wares went forth over the seas, thou filledst many peoples; thou didst enrich the kings of the earth with the abundance of thy substance and of thy merchandise.", "twenty": "", "jps": "When thy wares came forth out of the seas, thou didst fill many peoples; with the multitude of thy riches and of thy merchandise didst thou enrich the kings of the earth.", "acv": "When thy wares went forth out of the seas, thou filled many peoples. Thou enriched the kings of the earth with the multitude of thy riches and of thy merchandise.", "anderson": "", "haweis": "", "noyes": "When thy wares went forth from the seas, thou didst satisfy many nations; thou didst enrich the kings of the earth with the abundance of thy riches and thy merchandise.", "webster": "When thy wares went forth out of the seas, thou filledst many people; thou didst enrich the kings of the earth with the multitude of thy riches and of thy merchandise.", "vulgate": "quae in exitu negotiationum tuarum de mari implesti populos multos in multitudine divitiarum tuarum et populorum tuorum ditasti reges terrae;", "brenton": "How large a reward hast thou gained from the sea? thou hast filled nations out of thine abundance; and out of thy mixed merchandise thou hast enriched all the kings of the earth."}}, {"v": 34, "ref": "27:34", "o": "עֵ֛ת נִשְׁבֶּ֥רֶת מִ/יַּמִּ֖ים בְּ/מַֽעֲמַקֵּי מָ֑יִם מַעֲרָבֵ֥/ךְ וְ/כָל קְהָלֵ֖/ךְ בְּ/תוֹכֵ֥/ךְ נָפָֽלוּ", "en": {"kjv": "In the time when thou shalt be broken by the seas in the depths of the waters thy merchandise and all thy company in the midst of thee shall fall.", "web": "In the time that you were broken by the seas in the depths of the waters, your merchandise and all your company fell in your midst.", "bsb": "Now you are shattered by the seas in the depths of the waters; your merchandise and the people among you have gone down with you.", "asv": "In the time that thou wast broken by the seas in the depths of the waters, thy merchandise and all thy company did fall in the midst of thee.", "ylt": "The time of thy being broken by the seas in the depths of the waters, Thy merchandise and all thy assembly in thy midst have fallen.", "dra": "Now thou art destroyed by the sea, thy riches are in the bottom of the waters, and all the multitude that was in the midst of thee is fallen.", "bbe": "Now that you are broken by the seas in the deep waters, your goods and all your people will go down with you.", "geneva": "When thou shalt be broken by ye seas in the depths of the waters, thy marchandise and all thy multitude, which was in the mids of thee, shall fal.", "wycliffe": "Now thou art al to-brokun of the see, in the depthis of watris. Thi richessis and al thi multitude that was in the myddis of thee fellen doun;", "rotherham": "Now, thou art wrecked out of the seas In the depths of waters,— Thy merchandise and all thy gathered host In thy midst, have fallen.", "darby": "In the time [when] thou art broken by the seas, in the depths of the waters, thy merchandise and all thine assemblage in the midst of thee have fallen.", "twenty": "", "jps": "Now that thou art broken by the seas in the depths of the waters, and thy merchandise and all thy company are fallen in the midst of thee,", "acv": "In the time that thou were broken by the seas in the depths of the waters, thy merchandise and all thy company fell in the midst of thee.", "anderson": "", "haweis": "", "noyes": "Now thou art broken by the seas in the depth of the waters, and thy merchandise and all thy multitude in the midst of thee are fallen.", "webster": "In the time [when] thou shalt be broken by the seas in the depths of the waters, thy merchandise and all thy company in the midst of thee shall fall.", "vulgate": "nunc contrita es a mari in profundis aquarum opes tuae et omnis multitudo tua quae erat in medio tui ceciderunt;", "brenton": "Now art thou broken in the sea, thy traders are in the deep water, and all thy company in the midst of thee: all thy rowers have fallen."}}, {"v": 35, "ref": "27:35", "o": "כֹּ֚ל יֹשְׁבֵ֣י הָ/אִיִּ֔ים שָׁמְמ֖וּ עָלָ֑יִ/ךְ וּ/מַלְכֵי/הֶם֙ שָׂ֣עֲרוּ שַׂ֔עַר רָעֲמ֖וּ פָּנִֽים", "en": {"kjv": "All the inhabitants of the isles shall be astonished at thee, and their kings shall be sore afraid, they shall be troubled in their countenance.", "web": "All the inhabitants of the islands are astonished at you, and their kings are horribly afraid; they are troubled in their face.", "bsb": "All the people of the coastlands are appalled over you. Their kings shudder with fear; their faces are contorted.", "asv": "All the inhabitants of the isles are astonished at thee, and their kings are horribly afraid; they are troubled in their countenance.", "ylt": "All inhabitants of the isles have been astonished at thee, And their kings have been sore afraid, They have been troubled in countenance.", "dra": "All the inhabitants of the islands are astonished at thee: and all their kings being struck with the storm have changed their countenance.", "bbe": "All the people of the sea-lands are overcome with wonder at you, and their kings are full of fear, their faces are troubled.", "geneva": "All the inhabitantes of the yles shall be astonished at thee, and all their Kings shall be sore afraide and troubled in their countenance.", "wycliffe": "alle the dwelleris of ilis and the kyngis of tho weren astonyed on thee. Alle thei weren smytun with tempest, and chaungiden cheris;", "rotherham": "All the dwellers in the coastlands, Are astounded over thee,- And their kings have been made to shudder a shuddering, To be troubled in countenance.", "darby": "All the inhabitants of the isles are amazed at thee, and their kings are horribly afraid, [their] countenance is troubled.", "twenty": "", "jps": "All the inhabitants of the isles are appalled at thee, and their kings are horribly afraid, they are troubled in their countenance;", "acv": "All the inhabitants of the isles are astonished at thee, and their kings are horribly afraid; they are troubled in their countenance.", "anderson": "", "haweis": "", "noyes": "All the inhabitants of the isles are astonished at thee, and their kings shudder; they are troubled in their countenance.", "webster": "All the inhabitants of the isles shall be astonished at thee, and their kings shall be terribly afraid, they shall be troubled in [their] countenance.", "vulgate": "universi habitatores insularum obstipuerunt super te et reges earum omnes tempestate perculsi mutaverunt vultus;", "brenton": "All the dwellers in the islands have mourned over thee, and their kings have been utterly amazed, and their countenance has wept."}}, {"v": 36, "ref": "27:36", "o": "סֹֽחֲרִים֙ בָּ֣/עַמִּ֔ים שָׁרְק֖וּ עָלָ֑יִ/ךְ בַּלָּה֣וֹת הָיִ֔ית וְ/אֵינֵ֖/ךְ עַד עוֹלָֽם", "en": {"kjv": "The merchants among the people shall hiss at thee; thou shalt be a terror, and never shalt be any more.", "web": "The merchants among the peoples hiss at you; you are become a terror, and you shall nevermore have any being.", "bsb": "Those who trade among the nations hiss at you; you have come to a horrible end and will be no more.’”", "asv": "The merchants among the peoples hiss at thee; thou art become a terror, and thou shalt nevermore have any being.", "ylt": "Merchants among the peoples have shrieked for thee, Wastes thou hast been, and thou art not--to the age!'", "dra": "The merchants of people have hissed at thee: thou art brought to nothing, and thou shalt never be any more.", "bbe": "Those who do business among the peoples make sounds of surprise at you; you have become a thing of fear, you have come to an end for ever.", "geneva": "The marchants among the people shall hisse at thee: thou shalt be a terrour, and neuer shalt be any more.", "wycliffe": "the marchauntis of puplis hissiden on thee. Thou art brouyt to nouyt, and thou schalt not be til `in to with outen ende.", "rotherham": "The traders among the peoples, have hissed over thee: A terror, hast thou become, And, art not, Unto times age-abiding.", "darby": "The merchants among the peoples hiss at thee; thou art become a terror, and thou shalt never be any more.", "twenty": "", "jps": "The merchants among the peoples hiss at thee; thou art become a terror, and never shalt be any more.'", "acv": "The merchants among the peoples hiss at thee. Thou have become a horror, and thou shall nevermore have any being.", "anderson": "", "haweis": "", "noyes": "The merchants among the nations hiss at thee. Thou art a desolation, and shalt exist no more forever.\"", "webster": "The merchants among the people shall hiss at thee; thou shalt be a terror, and never [shalt be] any more.", "vulgate": "negotiatores populorum sibilaverunt super te ad nihilum deducta es et non eris usque in perpetuum;", "brenton": "Merchants from the nations have hissed at thee; thou art utterly destroyed, and shalt not be any more for ever."}}]}, {"c": 28, "verses": [{"v": 1, "ref": "28:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came again to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "The word of Jehovah came again unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "The word of the Lord came to me again, saying,", "geneva": "The word of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came again to me, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came again to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "28:2", "o": "בֶּן אָדָ֡ם אֱמֹר֩ לִ/נְגִ֨יד צֹ֜ר כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה יַ֣עַן גָּבַ֤הּ לִבְּ/ךָ֙ וַ/תֹּ֨אמֶר֙ אֵ֣ל אָ֔נִי מוֹשַׁ֧ב אֱלֹהִ֛ים יָשַׁ֖בְתִּי בְּ/לֵ֣ב יַמִּ֑ים וְ/אַתָּ֤ה אָדָם֙ וְֽ/לֹא אֵ֔ל וַ/תִּתֵּ֥ן לִבְּ/ךָ֖ כְּ/לֵ֥ב אֱלֹהִֽים", "en": {"kjv": "Son of man, say unto the prince of Tyrus, Thus saith the Lord God; Because thine heart is lifted up, and thou hast said, I am a God, I sit in the seat of God, in the midst of the seas; yet thou art a man, and not God, though thou set thine heart as the heart of God:", "web": "Son of man, tell the prince of Tyre, Thus says the Lord Yahweh: Because your heart is lifted up, and you have said, I am a god, I sit in the seat of God, in the midst of the seas; yet you are man, and not God, though you set your heart as the heart of God—", "bsb": "“Son of man, tell the ruler of Tyre that this is what the Lord GOD says: Your heart is proud, and you have said, ‘I am a god; I sit in the seat of gods in the heart of the sea.’ Yet you are a man and not a god, though you have regarded your heart as that of a god.", "asv": "Son of man, say unto the prince of Tyre, Thus saith the Lord Jehovah: Because thy heart is lifted up, and thou hast said, I am a god, I sit in the seat of God, in the midst of the seas; yet thou art man, and not God, though thou didst set thy heart as the heart of God;—", "ylt": "`Son of man, say to the leader of Tyre: Thus said the Lord Jehovah: Because thy heart hath been high, And thou dost say: A god I am , The habitation of God I have inhabited, In the heart of the seas, And thou art man, and not God, And thou givest out thy heart as the heart of God,", "dra": "Son of man, say to the prince of Tyre: Thus saith the Lord God: Because thy heart is lifted up, and thou hast said: I am God, and I sit in the chair of God in the heart of the sea: whereas thou art a man, and not God: and hast set thy heart as if it were the heart of God.", "bbe": "Son of man, say to the ruler of Tyre, This is what the Lord has said: Because your heart has been lifted up, and you have said, I am a god, I am seated on the seat of God in the heart of the seas; but you are man and not God, though you have made your heart as the heart of God:", "geneva": "Sonne of man, say vnto the prince of Tyrus, Thus saieth the Lord God, Because thine heart is exalted, and thou hast said, I am a God, I sit in the seat of God in ye mids of the sea, yet thou art but a man and not God, and though thou didest thinke in thine heart, that thou wast equall with God,", "wycliffe": "and he seide, Sone of man, seie thou to the prince of Tire, The Lord God seith these thingis, For thin herte was reisid, and thou seidist, Y am God, and Y sat in the chaier of God, in the herte of the see, sithen thou art man and not God, and thou yauest thin herte as the herte of God; lo!", "rotherham": "Son of man Say to the Prince of Tyre. Thus, saith My Lord. Yahweh— Because lofty, is thy heart and thou hast said A GOD, am I, In the seat of God, have I taken my seat In the heart of the seas; Whereas thou art a man, and not a GOD, But hast set thy heart as the heart of God:", "darby": "Son of man, say unto the prince of Tyre, Thus saith the Lord Jehovah: Because thy heart is lifted up, and thou hast said, I am agod, I sit [in] the seat ofGod, in the heart of the seas, (and thou art a man, and notGod,) and thou settest thy heart as the heart ofGod:", "twenty": "", "jps": "'Son of man, say unto the prince of Tyre: Thus saith the L-rd GOD: because thy heart is lifted up, and thou hast said: I am a god, I sit in the seat of G-d, in the heart of the seas; yet thou art man, and not G-d, though thou didst set thy heart as the heart of G-d--", "acv": "Son of man, say to the ruler of Tyre, Thus says the lord Jehovah: Because thy heart is lifted up, and thou have said, I am a god. I sit in the seat of God, in the midst of the seas. Yet thou are man, and not God, though thou did set thy heart as the heart of God.", "anderson": "", "haweis": "", "noyes": "Son of man, say to the prince of Tyre, Thus saith the Lord Jehovah: Because thy heart is lifted up, and thou hast said, \"I am a god, I sit in the seat of a god, in the midst of the seas\"; and though thou art man, not God, yet settest thy heart as the heart of a god,—", "webster": "Son of man, say to the prince of Tyre, Thus saith the Lord GOD; Because thy heart [is] lifted up, and thou hast said, I [am] a god, I sit [in] the seat of God, in the midst of the seas; yet thou [art] a man, and not God, though thou settest thy heart as the heart of God:", "vulgate": "fili hominis dic principi Tyri haec dicit Dominus Deus eo quod elevatum est cor tuum et dixisti Deus ego sum et in cathedra Dei sedi in corde maris cum sis homo et non Deus et dedisti cor tuum quasi cor Dei;", "brenton": "And thou, son of man, say to the prince of Tyrus, Thus saith the Lord; Because thine heart has been exalted, and thou hast said, I am God, I have inhabited the dwelling of God in the heart of the sea; yet thou art man and not God, though thou hast set thine heart as the heart of God:"}}, {"v": 3, "ref": "28:3", "o": "הִנֵּ֥ה חָכָ֛ם אַתָּ֖ה מ/דנאל מִ/דָּֽנִיֵּ֑אל כָּל סָת֖וּם לֹ֥א עֲמָמֽוּ/ךָ", "en": {"kjv": "Behold, thou art wiser than Daniel; there is no secret that they can hide from thee:", "web": "behold, you are wiser than Daniel; there is no secret that is hidden from you;", "bsb": "Behold, you are wiser than Daniel; no secret is hidden from you!", "asv": "behold, thou art wiser than Daniel; there is no secret that is hidden from thee;", "ylt": "Lo, thou art wiser than Daniel, No hidden thing have they concealed from thee.", "dra": "Behold thou art wiser than Daniel: no secret is hid from thee.", "bbe": "See, you are wiser than Daniel; there is no secret which is deeper than your knowledge:", "geneva": "Behold, thou art wiser then Daniel: there is no secrete, that they can hide from thee.", "wycliffe": "thou art wisere than Danyel, ech priuetee is not hid fro thee;", "rotherham": "Lo! wiser, thou than Daniel,— No secret, have they hidden from thee:", "darby": "behold, thou art wiser than Daniel! nothing secret is obscure for thee;", "twenty": "", "jps": "Behold, thou art wiser than Daniel! there is no secret that they can hide from thee!", "acv": "Behold, thou are wiser than Daniel. There is no secret that is hidden from thee.", "anderson": "", "haweis": "", "noyes": "behold, thou art wiser than Daniel; there is no secret which can be hidden from thee;", "webster": "Behold, thou [art] wiser than Daniel; there is no secret that they can hide from thee:", "vulgate": "ecce sapientior es tu Danihele omne secretum non est absconditum a te;", "brenton": "art thou wiser than Daniel? or have not the wise instructed thee with their knowledge?"}}, {"v": 4, "ref": "28:4", "o": "בְּ/חָכְמָֽתְ/ךָ֙ וּ/בִ/תְבוּנָ֣תְ/ךָ֔ עָשִׂ֥יתָ לְּ/ךָ֖ חָ֑יִל וַ/תַּ֛עַשׂ זָהָ֥ב וָ/כֶ֖סֶף בְּ/אוֹצְרוֹתֶֽי/ךָ", "en": {"kjv": "With thy wisdom and with thine understanding thou hast gotten thee riches, and hast gotten gold and silver into thy treasures:", "web": "by your wisdom and by your understanding you have gotten yourself riches, and have gotten gold and silver into your treasures;", "bsb": "By your wisdom and understanding you have gained your wealth and amassed gold and silver for your treasuries.", "asv": "by thy wisdom and by thine understanding thou hast gotten thee riches, and hast gotten gold and silver into thy treasures;", "ylt": "By thy wisdom and by thine understanding Thou hast made for thee wealth, And makest gold and silver in thy treasuries.", "dra": "In thy wisdom and thy understanding thou hast made thyself strong: and hast gotten gold an silver into thy treasures.", "bbe": "By your wisdom and deep knowledge you have got power for yourself, and put silver and gold in your store-houses:", "geneva": "With thy wisedome and thine vnderstanding thou hast gotten thee riches, and hast gotten golde and siluer into thy treasures.", "wycliffe": "in thi wisdom and prudence thou madist to thee strengthe, and thou gatist to thee gold and siluer in thi tresouris;", "rotherham": "In thy wisdom and in thine understanding, hast thou gotten thee wealth,— And hast gotten gold and silver into thy treasuries:", "darby": "by thy wisdom and by thine understanding thou hast gotten thee riches, and hast gotten gold and silver into thy treasures;", "twenty": "", "jps": "By thy wisdom and by thy discernment thou hast gotten thee riches, and hast gotten gold and silver into thy treasures;", "acv": "By thy wisdom and by thine understanding thou have gotten thee riches, and have gotten gold and silver into thy treasures.", "anderson": "", "haweis": "", "noyes": "by thy wisdom and by thine understanding thou hast gotten thee riches, and hast gotten gold and silver in thy treasures;", "webster": "With thy wisdom and with thy understanding thou hast gained for thee riches, and hast gained gold and silver into thy treasures:", "vulgate": "in sapientia et prudentia tua fecisti tibi fortitudinem et adquisisti aurum et argentum in thesauris tuis;", "brenton": "Hast thou gained power for thyself by thine own knowledge or thine own prudence, and gotten gold and silver in thy treasures?"}}, {"v": 5, "ref": "28:5", "o": "בְּ/רֹ֧ב חָכְמָתְ/ךָ֛ בִּ/רְכֻלָּתְ/ךָ֖ הִרְבִּ֣יתָ חֵילֶ֑/ךָ וַ/יִּגְבַּ֥הּ לְבָבְ/ךָ֖ בְּ/חֵילֶֽ/ךָ", "en": {"kjv": "By thy great wisdom and by thy traffick hast thou increased thy riches, and thine heart is lifted up because of thy riches:", "web": "by your great wisdom and by your traffic you have increased your riches, and your heart is lifted up because of your riches—", "bsb": "By your great skill in trading you have increased your wealth, but your heart has grown proud because of it.", "asv": "by thy great wisdom and by thy traffic hast thou increased thy riches, and thy heart is lifted up because of thy riches;—", "ylt": "By the abundance of thy wisdom, Through thy merchandise, Thou hast multiplied thy wealth, And high is thy heart through thy wealth.", "dra": "By the greatness of thy wisdom, and by thy traffic thou hast increased thy strength: and thy heart is lifted up with thy strength.", "bbe": "By your great wisdom and by your trade your power is increased, and your heart is lifted up because of your power:", "geneva": "By thy great wisedome and by thine occupying hast thou increased thy riches, and thine heart is lifted vp because of thy riches.", "wycliffe": "in the multitude of thi wisdom, and in thi marchaundie thou multipliedist to thee strengthe, and thin herte was reisid in thi strengthe;", "rotherham": "By the greatness of thy wisdom and by thy traffic, hast thou multiplied thy riches, -And thy heart hath become lofty in thy riches:", "darby": "by thy great wisdom thou hast by thy traffic increased thy riches, and thy heart is lifted up because of thy riches.", "twenty": "", "jps": "In thy great wisdom by thy traffic hast thou increased thy riches, and thy heart is lifted up because of thy riches--", "acv": "By thy great wisdom and by thy traffic thou have increased thy riches. And thy heart is lifted up because of thy riches.", "anderson": "", "haweis": "", "noyes": "by thy great wisdom, by thy traffic, thou hast increased thy riches, and thy heart is lifted up because of thy wealth,—", "webster": "By thy great wisdom [and] by thy traffick hast thou increased thy riches, and thy heart is lifted up because of thy riches:", "vulgate": "in multitudine sapientiae tuae et in negotiatione tua multiplicasti tibi fortitudinem et elevatum est cor tuum in robore tuo;", "brenton": "By thy abundant knowledge and thy traffic thou hast multiplied thy power; thy heart has been lifted up by thy power."}}, {"v": 6, "ref": "28:6", "o": "לָ/כֵ֕ן כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה יַ֛עַן תִּתְּ/ךָ֥ אֶת לְבָבְ/ךָ֖ כְּ/לֵ֥ב אֱלֹהִֽים", "en": {"kjv": "Therefore thus saith the Lord God; Because thou hast set thine heart as the heart of God;", "web": "therefore thus says the Lord Yahweh: Because you have set your heart as the heart of God,", "bsb": "Therefore this is what the Lord GOD says: Because you regard your heart as the heart of a god,", "asv": "therefore thus saith the Lord Jehovah: Because thou hast set thy heart as the heart of God,", "ylt": "Therefore, thus said the Lord Jehovah: Because of thy giving out thy heart as the heart of God,", "dra": "Therefore, thus saith the Lord God: Because thy heart is lifted up as the heart of God:", "bbe": "For this cause the Lord has said: Because you have made your heart as the heart of God,", "geneva": "Therefore thus sayeth the Lord God, Because thou didest thinke in thine heart, that thou wast equall with God,", "wycliffe": "therfor the Lord God seith these thingis, For thin herte was reisid as the herte of God, therfor lo!", "rotherham": "Therefore, Thus saith My Lord Yahweh,— Because thou hast set thy heart as the heart of God,", "darby": "Therefore thus saith the Lord Jehovah: Because thou hast set thy heart as the heart ofGod,", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: because thou hast set thy heart as the heart of G-d;", "acv": "Therefore thus says the lord Jehovah: Because thou have set thy heart as the heart of God,", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: Because thou settest thy heart as the heart of a god, therefore,", "webster": "Therefore thus saith the Lord GOD; Because thou hast set thy heart as the heart of God;", "vulgate": "propterea haec dicit Dominus Deus eo quod elevatum est cor tuum quasi cor Dei;", "brenton": "Therefore thus saith the Lord; Since thou hast set thine heart as the hart of God;"}}, {"v": 7, "ref": "28:7", "o": "לָ/כֵ֗ן הִנְ/נִ֨י מֵבִ֤יא עָלֶ֨י/ךָ֙ זָרִ֔ים עָרִיצֵ֖י גּוֹיִ֑ם וְ/הֵרִ֤יקוּ חַרְבוֹתָ/ם֙ עַל יְפִ֣י חָכְמָתֶ֔/ךָ וְ/חִלְּל֖וּ יִפְעָתֶֽ/ךָ", "en": {"kjv": "Behold, therefore I will bring strangers upon thee, the terrible of the nations: and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "web": "therefore, behold, I will bring strangers on you, the terrible of the nations; and they shall draw their swords against the beauty of your wisdom, and they shall defile your brightness.", "bsb": "behold, I will bring foreigners against you, the most ruthless of nations. They will draw their swords against the beauty of your wisdom and will defile your splendor.", "asv": "therefore, behold, I will bring strangers upon thee, the terrible of the nations; and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "ylt": "Therefore, lo, I am bringing in against thee strangers, The terrible of the nations, And they have drawn out their swords Against the beauty of thy wisdom, And they have pierced thy brightness.", "dra": "Therefore behold, I will bring upon thee strangers: the strongest of the nations: and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy beauty.", "bbe": "See, I am sending against you strange men, feared among the nations: they will let loose their swords against your bright wisdom, they will make your glory a common thing.", "geneva": "Behold, therefore I wil bring strangers vpon thee, euen the terrible nations: and they shall drawe their swordes against the beautie of thy wisedome, and they shall defile thy brightnes.", "wycliffe": "Y schal brynge on thee aliens, the strongeste of hethene. And thei schulen make nakid her swerdis on the fairnesse of thi wisdom, and thei schulen defoule thi fairnesse.", "rotherham": "Therefore behold me! bringing upon thee aliens, The terrible ones of the nations,- And they shall unsheathe their swords over the beauty of thy wisdom, And profane thy splendour:", "darby": "therefore behold, I will bring strangers upon thee, the terrible of the nations; and they shall draw their swords against the beauty of thy wisdom, and they shall tarnish thy brightness.", "twenty": "", "jps": "Therefore, behold, I will bring strangers upon thee, the terrible of the nations; and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "acv": "therefore, behold, I will bring strangers upon thee, the terrible of the nations, and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "anderson": "", "haweis": "", "noyes": "behold, I will bring upon thee strangers, the terrible of the nations; and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "webster": "Behold, therefore I will bring strangers upon thee, the terrible of the nations: and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.", "vulgate": "idcirco ecce ego adducam super te alienos robustissimos gentium et nudabunt gladios suos super pulchritudinem sapientiae tuae et polluent decorem tuum;", "brenton": "because of this, behold, I will bring on thee strange plagues from the nations; and they shall draw their swords against thee, and against the beauty of thy knowledge,"}}, {"v": 8, "ref": "28:8", "o": "לַ/שַּׁ֖חַת יֽוֹרִד֑וּ/ךָ וָ/מַ֛תָּה מְמוֹתֵ֥י חָלָ֖ל בְּ/לֵ֥ב יַמִּֽים", "en": {"kjv": "They shall bring thee down to the pit, and thou shalt die the deaths of them that are slain in the midst of the seas.", "web": "They shall bring you down to the pit; and you shall die the death of those who are slain, in the heart of the seas.", "bsb": "They will bring you down to the Pit, and you will die a violent death in the heart of the seas.", "asv": "They shall bring thee down to the pit; and thou shalt die the death of them that are slain, in the heart of the seas.", "ylt": "To destruction they bring thee down, Thou diest by the deaths of the wounded, in the heart of the seas.", "dra": "They shall kill thee, and bring thee down: and thou shalt die the death of them that are slain in the heart of the sea.", "bbe": "They will send you down to the underworld, and your death will be the death of those who are put to the sword in the heart of the seas.", "geneva": "They shall cast thee downe to the pit, and thou shalt die the death of them, that are slaine in the middes of the sea.", "wycliffe": "Thei schulen sle, and drawe doun thee; and thou schalt die bi the deth of vncircumcidid men, in the herte of the see.", "rotherham": "To the pit, shall they take thee down,- And thou shalt die the deaths of one thrust through, In the heart of the seas.", "darby": "They shall bring thee down to the pit, and thou shalt die the deaths of those that are slain in the heart of the seas.", "twenty": "", "jps": "They shall bring thee down to the pit; and thou shalt die the deaths of them that are slain, in the heart of the seas.", "acv": "They shall bring thee down to the pit, and thou shall die the death of those who are slain, in the heart of the seas.", "anderson": "", "haweis": "", "noyes": "They shall bring thee down to the pit, and thou shalt die the death of the slain, in the midst of the seas.", "webster": "They shall bring thee down to the pit, and thou shalt die the deaths of [them that are] slain in the midst of the seas.", "vulgate": "interficient et detrahent te et morieris interitu occisorum in corde maris;", "brenton": "and they shall bring down thy beauty to destruction. And they shall bring thee down; and thou shalt die the death of the slain in the heart of the sea."}}, {"v": 9, "ref": "28:9", "o": "הֶ/אָמֹ֤ר תֹּאמַר֙ אֱלֹהִ֣ים אָ֔נִי לִ/פְנֵ֖י הֹֽרְגֶ֑/ךָ וְ/אַתָּ֥ה אָדָ֛ם וְ/לֹא אֵ֖ל בְּ/יַ֥ד מְחַלְלֶֽי/ךָ", "en": {"kjv": "Wilt thou yet say before him that slayeth thee, I am God? but thou shalt be a man, and no God, in the hand of him that slayeth thee.", "web": "Will you yet say before him who kills you, I am God? but you are man, and not God, in the hand of him who wounds you.", "bsb": "Will you still say, ‘I am a god,’ in the presence of those who slay you? You will be only a man, not a god, in the hands of those who wound you.", "asv": "Wilt thou yet say before him that slayeth thee, I am God? but thou art man, and not God, in the hand of him that woundeth thee.", "ylt": "Dost thou really say, `I am God,' Before him who is slaying thee? And thou art man, and not God, In the hand of him who is piercing thee.", "dra": "Wilt thou yet say before them that slay thee: I am God; whereas thou art a man, and not God, in the hand of them that slay thee?", "bbe": "Will you say, in the face of those who are taking your life, I am God? but you are man and not God in the hands of those who are wounding you.", "geneva": "Wilt thou say then before him, that slayeth thee, I am a god? but thou shalt be a man, and no God, in the hands of him that slayeth thee.", "wycliffe": "Whether thou schalt seie, and speke, Y am God, bifore hem that sleen thee; sithen thou art a man, and not God?", "rotherham": "Wilt thou really say, God, am I, before him who is slaying thee; When, thou, art a man and not a God, in the hand of them who are piercing thee?", "darby": "Wilt thou then say before him that slayeth thee, I amGod? but thou shalt be a man, and notGod, in the hand of him that pierceth thee.", "twenty": "", "jps": "Wilt thou yet say before him that slayeth thee: I am G-d? But thou art man, and not G-d, in the hand of them that defile thee.", "acv": "Will thou yet say before him who slays thee, I am God? But thou are man, and not God, in the hand of him who wounds thee.", "anderson": "", "haweis": "", "noyes": "Wilt thou yet say, \"I am a god,\" before him that slayeth thee? Thou shalt be man, and not God, in the hand of him that slayeth thee.", "webster": "Wilt thou yet say before him that slayeth thee, I [am] God? but thou [shalt be] a man, and no god, in the hand of him that slayeth thee.", "vulgate": "numquid dicens loqueris Deus ego sum coram interficientibus te cum sis homo et non Deus in manu occidentium te;", "brenton": "Wilt thou indeed say, I am God, before them that slay thee? whereas thou art man, and not God."}}, {"v": 10, "ref": "28:10", "o": "מוֹתֵ֧י עֲרֵלִ֛ים תָּמ֖וּת בְּ/יַד זָרִ֑ים כִּ֚י אֲנִ֣י דִבַּ֔רְתִּי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thou shalt die the deaths of the uncircumcised by the hand of strangers: for I have spoken it, saith the Lord God.", "web": "You shall die the death of the uncircumcised by the hand of strangers: for I have spoken it, says the Lord Yahweh.", "bsb": "You will die the death of the uncircumcised at the hands of foreigners. For I have spoken, declares the Lord GOD.”", "asv": "Thou shalt die the death of the uncircumcised by the hand of strangers: for I have spoken it, saith the Lord Jehovah.", "ylt": "The deaths of the uncircumcised thou diest, By the hand of strangers, for I have spoken, An affirmation of the Lord Jehovah.'", "dra": "Thou shalt die the death of the uncircumcised by the hand of strangers: for I have spoken it, saith the Lord God.", "bbe": "Your death will be the death of those who are without circumcision, by the hands of men from strange lands: for I have said it, says the Lord.", "geneva": "Thou shalt die the death of the vncircumcised by the hands of stragers: for I haue spoken it, sayth the Lord God.", "wycliffe": "In the hond of hem that sleen thee, bi deth of vncircumcidid men, thou schalt die in the hond of aliens; for Y the Lord spak, seith the Lord God.", "rotherham": "The deaths of the uncircumcised, shalt thou die by the hand of aliens,— For I have spoken, Declareth My Lord Yahweh.", "darby": "Thou shalt die the deaths of the uncircumcised, by the hand of strangers: for I have spoken [it], saith the Lord Jehovah.", "twenty": "", "jps": "Thou shalt die the deaths of the uncircumcised by the hand of strangers; for I have spoken, saith the L-rd GOD.'", "acv": "Thou shall die the death of the uncircumcised by the hand of strangers. For I have spoken it, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thou shalt die the death of the uncircumcised, by the hand of strangers; for I have spoken it, saith the Lord Jehovah.", "webster": "Thou shalt die the deaths of the uncircumcised by the hand of strangers: for I have spoken [it], saith the Lord GOD.", "vulgate": "morte incircumcisorum morieris in manu alienorum quia ego locutus sum ait Dominus Deus;", "brenton": "Thou shalt perish by the hands of strangers among the multitude of the uncircumcised: for I have spoken it, saith the Lord."}}, {"v": 11, "ref": "28:11", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying: Son of man, take up a lamentation upon the king of Tyre:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moreouer the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide, Thou, sone of man, reise thou weilyng on the kyng of Tire;", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens fili hominis leva planctum super regem Tyri;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 12, "ref": "28:12", "o": "בֶּן אָדָ֕ם שָׂ֥א קִינָ֖ה עַל מֶ֣לֶךְ צ֑וֹר וְ/אָמַ֣רְתָּ לּ֗/וֹ כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה אַתָּה֙ חוֹתֵ֣ם תָּכְנִ֔ית מָלֵ֥א חָכְמָ֖ה וּ/כְלִ֥יל יֹֽפִי", "en": {"kjv": "Son of man, take up a lamentation upon the king of Tyrus, and say unto him, Thus saith the Lord God; Thou sealest up the sum, full of wisdom, and perfect in beauty.", "web": "Son of man, take up a lamentation over the king of Tyre, and tell him, Thus says the Lord Yahweh: You seal up the sum, full of wisdom, and perfect in beauty.", "bsb": "“Son of man, take up a lament for the king of Tyre and tell him that this is what the Lord GOD says: ‘You were the seal of perfection, full of wisdom and perfect in beauty.", "asv": "Son of man, take up a lamentation over the king of Tyre, and say unto him, Thus saith the Lord Jehovah: Thou sealest up the sum, full of wisdom, and perfect in beauty.", "ylt": "`Son of man, lift up a lamentation for the king of Tyre, And thou hast said to him: Thus said the Lord Jehovah: Thou art sealing up a measurement, Full of wisdom, and perfect in beauty.", "dra": "And say to him: Thus saith the Lord God: Thou wast the seal of resemblance, full of wisdom, and perfect in beauty.", "bbe": "Son of man, make a song of grief for the king of Tyre, and say to him, This is what the Lord has said: You are all-wise and completely beautiful;", "geneva": "Sonne of man, take vp a lamentation vpon the King of Tyrus, and say vnto him, Thus sayeth the Lord God, Thou sealest vp the summe, and art full of wisedome and perfite in beautie.", "wycliffe": "and thou schalt seie to hym, The Lord God seith these thingis, Thou a preente of licnesse, ful of wisdom, perfit in fairnesse,", "rotherham": "Son of man Take thou up a dirge over the king of Tyre,— And thou shalt say to him Thus saith My Lord. Yahweh, Thou wast of finished proportions, Full of wisdom and Perfect in beauty:", "darby": "Son of man, take up a lamentation upon the king of Tyre, and say unto him, Thus saith the Lord Jehovah: Thou, who sealest up the measure of perfection, full of wisdom and perfect in beauty,", "twenty": "", "jps": "'Son of man, take up a lamentation for the king of Tyre, and say unto him: Thus saith the L-rd GOD: Thou seal most accurate, full of wisdom, and perfect in beauty,", "acv": "Son of man, take up a lamentation over the king of Tyre, and say to him, Thus says the lord Jehovah: Thou seal up the sum, full of wisdom, and perfect in beauty.", "anderson": "", "haweis": "", "noyes": "Son of man, take up a lamentation upon the king of Tyre, and say to him, Thus saith the Lord Jehovah:—Thou wast a finished signet, Full of wisdom and perfect in beauty;", "webster": "Son of man, take up a lamentation upon the king of Tyre, and say to him, Thus saith the Lord GOD; Thou sealest up the sum, full of wisdom, and perfect in beauty.", "vulgate": "et dices ei haec dicit Dominus Deus tu signaculum similitudinis plenus sapientia et perfectus decore;", "brenton": "Son of man, take up a lamentation for the prince of Tyre, and say to him, Thus saith the Lord God; Thou art a seal of resemblance, and crown of beauty."}}, {"v": 13, "ref": "28:13", "o": "בְּ/עֵ֨דֶן גַּן אֱלֹהִ֜ים הָיִ֗יתָ כָּל אֶ֨בֶן יְקָרָ֤ה מְסֻכָתֶ֨/ךָ֙ אֹ֣דֶם פִּטְדָ֞ה וְ/יָהֲלֹ֗ם תַּרְשִׁ֥ישׁ שֹׁ֨הַם֙ וְ/יָ֣שְׁפֵ֔ה סַפִּ֣יר נֹ֔פֶךְ וּ/בָרְקַ֖ת וְ/זָהָ֑ב מְלֶ֨אכֶת תֻּפֶּ֤י/ךָ וּ/נְקָבֶ֨י/ךָ֙ בָּ֔/ךְ בְּ/י֥וֹם הִבָּרַאֲ/ךָ֖ כּוֹנָֽנוּ", "en": {"kjv": "Thou hast been in Eden the garden of God; every precious stone was thy covering, the sardius, topaz, and the diamond, the beryl, the onyx, and the jasper, the sapphire, the emerald, and the carbuncle, and gold: the workmanship of thy tabrets and of thy pipes was prepared in thee in the day that thou wast created.", "web": "You were in Eden, the garden of God; every precious stone adorned you: ruby, topaz, emerald, chrysolite, onyx, jasper, sapphire, turquoise, and beryl. Gold work of tambourines and of pipes was in you. In the day that you were created they were prepared.", "bsb": "You were in Eden, the garden of God. Every kind of precious stone adorned you: ruby, topaz, and diamond, beryl, onyx, and jasper, sapphire, turquoise, and emerald. Your mountings and settings were crafted in gold, prepared on the day of your creation.", "asv": "Thou wast in Eden, the garden of God; every precious stone was thy covering, the sardius, the topaz, and the diamond, the beryl, the onyx, and the jasper, the sapphire, the emerald, and the carbuncle, and gold: the workmanship of thy tabrets and of thy pipes was in thee; in the day that thou wast created they were prepared.", "ylt": "In Eden, the garden of God, thou hast been, Every precious stone thy covering, Ruby, topaz, and diamond, beryl, onyx, and jasper, Sapphire, emerald, and carbuncle, and gold, The workmanship of thy tabrets, and of thy pipes, In thee in the day of thy being produced, have been prepared.", "dra": "Thou wast in the pleasures of the paradise of God: every precious stone was thy covering: the sardius, the topaz, and the jasper, the chrysolite, and the onyx, and the beryl, the sapphire, and the carbuncle, and the emerald: gold the work of thy beauty: and thy pipes were prepared in the day that thou wast created.", "bbe": "You were in Eden, the garden of God; every stone of great price was your clothing, the sardius, the topaz, and the diamond, the beryl, the onyx, and the jasper, the emerald and the carbuncle: your store-houses were full of gold, and things of great price were in you; in the day when you were made they were got ready.", "geneva": "Thou hast ben in Eden the garden of God: euery precious stone was in thy garment, the rubie, the topaze and the diamonde, the chrysolite, the onix, and the iasper, the saphir, emeraude, and the carbuncle and golde: the woorkemanship of thy timbrels, and of thy pipes was prepared in thee in the day that thou wast created.", "wycliffe": "were in delicis of paradijs of God. Ech preciouse stoon was thin hilyng, sardius, topacius, and iaspis, crisolitus, and onix, and birille, safire, and carbuncle, and smaragde; also gold was the werk of thi fairnesse, and thin hoolis weren maad redi, in the dai in which thou were maad.", "rotherham": "In Eden the garden of God, thou wast. Of every precious stone, was thy covering-Sardius. topaz, and diamond, Chrysolite beryl, and jasper, Sapphire carbuncle and emerald,- And of gold, was the work of thy timbrels and thy flutes within thee, In the day thou wast created, were they prepared:", "darby": "thou wast in Eden, the garden ofGod. Every precious stone was thy covering: the sardius, the topaz, and the diamond, the chrysolite, the onyx, and the jasper, the sapphire, the carbuncle, and the emerald, and gold. The workmanship of thy tambours and of thy pipes was in thee: in the day that thou wast created were they prepared.", "twenty": "", "jps": "thou wast in Eden the garden of G-d; every precious stone was thy covering, the carnelian, the topaz, and the emerald, the beryl, the onyx, and the jasper, the sapphire, the carbuncle, and the smaragd, and gold; the workmanship of thy settings and of thy sockets was in thee, in the day that thou wast created they were prepared.", "acv": "Thou were in Eden, the garden of God. Every precious stone was thy covering, the sardius, the topaz, and the diamond, the beryl, the onyx, and the jasper, the sapphire, the emerald, and the carbuncle, and gold. The workmanship of thy tambourine and of thy pipes was in thee. In the day that thou were created they were prepared.", "anderson": "", "haweis": "", "noyes": "In Eden, the garden of God, thou didst dwell; Every precious stone was thy covering, The ruby, the topaz, and the diamond, The chrysolite, the onyx, and the jasper, The sapphire, the carbuncle, and the emerald, and gold. The workmanship of thy jewel-holes was within thee; On the day when thou wast born were they prepared.", "webster": "Thou hast been in Eden the garden of God; every precious stone [was] thy covering, the sardius, topaz, and the diamond, the beryl, the onyx, and the jasper, the sapphire, the emerald, and the carbuncle, and gold: the workmanship of thy tabrets and of thy pipes was prepared in thee in the day that thou wast created.", "vulgate": "in deliciis paradisi Dei fuisti omnis lapis pretiosus operimentum tuum sardius topazius et iaspis chrysolitus et onyx et berillus sapphyrus et carbunculus et zmaragdus aurum opus decoris tui et foramina tua in die qua conditus es praeparata sunt;", "brenton": "Thou wast in the delight of the paradise of God; thou hast bound upon thee every precious stone, the sardius, and topaz, and emerald, and carbuncle, and sapphire, and jasper, and silver, and gold, and ligure, and agate, and amethyst, and chrysolite, and beryl, and onyx: and thou hast filled thy treasures and thy stores in thee with gold."}}, {"v": 14, "ref": "28:14", "o": "אַ֨תְּ כְּר֔וּב מִמְשַׁ֖ח הַ/סּוֹכֵ֑ךְ וּ/נְתַתִּ֗י/ךָ בְּ/הַ֨ר קֹ֤דֶשׁ אֱלֹהִים֙ הָיִ֔יתָ בְּ/ת֥וֹךְ אַבְנֵי אֵ֖שׁ הִתְהַלָּֽכְתָּ", "en": {"kjv": "Thou art the anointed cherub that covereth; and I have set thee so: thou wast upon the holy mountain of God; thou hast walked up and down in the midst of the stones of fire.", "web": "You were the anointed cherub who covers: and I set you, so that you were on the holy mountain of God; you have walked up and down in the midst of the stones of fire.", "bsb": "You were anointed as a guardian cherub, for I had ordained you. You were on the holy mountain of God; you walked among the fiery stones.", "asv": "Thou wast the anointed cherub that covereth: and I set thee, so that thou wast upon the holy mountain of God; thou hast walked up and down in the midst of the stones of fire.", "ylt": "Thou art an anointed cherub who is covering, And I have set thee in the holy mount, God thou hast been, In the midst of stones of fire thou hast walked up and down.", "dra": "Thou a cherub stretched out, and protecting, and I set thee in the holy mountain of God, thou hast walked in the midst of the stones of fire.", "bbe": "I gave you your place with the winged one; I put you on the mountain of God; you went up and down among the stones of fire.", "geneva": "Thou art the anointed Cherub, that couereth, and I haue set thee in honour: thou wast vpon the holy mountaine of God: thou hast walked in the middes of the stones of fire.", "wycliffe": "Thou were cherub holdun forth, and hilynge; and Y settide thee in the hooli hil of God. In the myddis of stoonus set a fier thou yedist,", "rotherham": "Thou, wast the anointed cherub that covered,— When I appointed thee, in the holy mount of God, thou wast, Amid stones of fire, thou didst walk to and fro:", "darby": "Thou wast the anointed covering cherub, and I had set thee [so]: thou wast upon the holy mountain ofGod; thou didst walk up and down in the midst of stones of fire.", "twenty": "", "jps": "Thou wast the far-covering cherub; and I set thee, so that thou wast upon the holy mountain of G-d; thou hast walked up and down in the midst of stones of fire.", "acv": "Thou were the anointed cherub who covers. And I set thee, so that thou were upon the holy mountain of God. Thou have walked up and down in the midst of the stones of fire.", "anderson": "", "haweis": "", "noyes": "Thou wast an outspread, covering cherub; I set thee upon the holy mountain of God; Thou didst walk in the midst of the stones of fire.", "webster": "Thou [art] the anointed cherub that covereth; and I have set thee [so]: thou wast upon the holy mountain of God; thou hast walked up and down in the midst of the stones of fire.", "vulgate": "tu cherub extentus et protegens et posui te in monte sancto Dei in medio lapidum ignitorum ambulasti;", "brenton": "From the day that thou wast created thou wast with the cherub: I set thee on the holy mount of God; thou wast in the midst of the stones of fire."}}, {"v": 15, "ref": "28:15", "o": "תָּמִ֤ים אַתָּה֙ בִּ/דְרָכֶ֔י/ךָ מִ/יּ֖וֹם הִבָּֽרְאָ֑/ךְ עַד נִמְצָ֥א עַוְלָ֖תָ/ה בָּֽ/ךְ", "en": {"kjv": "Thou wast perfect in thy ways from the day that thou wast created, till iniquity was found in thee.", "web": "You were perfect in your ways from the day that you were created, until unrighteousness was found in you.", "bsb": "From the day you were created you were blameless in your ways— until wickedness was found in you.", "asv": "Thou wast perfect in thy ways from the day that thou wast created, till unrighteousness was found in thee.", "ylt": "Perfect art thou in thy ways, From the day of thy being produced, Till perversity hath been found in thee.", "dra": "Thou wast perfect in thy ways from the day of thy creation, until iniquity was found in thee.", "bbe": "There has been no evil in your ways from the day when you were made, till sin was seen in you.", "geneva": "Thou wast perfite in thy wayes from the day that thou wast created, till iniquitie was found in thee.", "wycliffe": "perfit in thi weies fro the dai of thi makyng, til wickidnesse was foundun in thee.", "rotherham": "Complete, wast thou in thy ways, from the day thou wast created,- Until perversity was found in thee.", "darby": "Thou wast perfect in thy ways, from the day that thou wast created, till unrighteousness was found in thee.", "twenty": "", "jps": "Thou wast perfect in thy ways from the day that thou wast created, till unrighteousness was found in thee.", "acv": "Thou were perfect in thy ways from the day that thou were created, till unrighteousness was found in thee.", "anderson": "", "haweis": "", "noyes": "Thou wast prosperous in thy ways from the day that thou wast born Until iniquity was found in thee.", "webster": "Thou [wast] perfect in thy ways from the day that thou wast created, till iniquity was found in thee.", "vulgate": "perfectus in viis tuis a die conditionis tuae donec inventa est iniquitas in te;", "brenton": "Thou wast faultless in thy days, from the day that thou wast created, until iniquity was found in thee."}}, {"v": 16, "ref": "28:16", "o": "בְּ/רֹ֣ב רְכֻלָּתְ/ךָ֗ מָל֧וּ תוֹכְ/ךָ֛ חָמָ֖ס וַֽ/תֶּחֱטָ֑א וָ/אֶחַלֶּלְ/ךָ֩ מֵ/הַ֨ר אֱלֹהִ֤ים וָֽ/אַבֶּדְ/ךָ֙ כְּר֣וּב הַ/סֹּכֵ֔ךְ מִ/תּ֖וֹךְ אַבְנֵי אֵֽשׁ", "en": {"kjv": "By the multitude of thy merchandise they have filled the midst of thee with violence, and thou hast sinned: therefore I will cast thee as profane out of the mountain of God: and I will destroy thee, O covering cherub, from the midst of the stones of fire.", "web": "By the abundance of your traffic they filled your midst with violence, and you have sinned: therefore I have cast you as profane out of the mountain of God; and I have destroyed you, covering cherub, from the midst of the stones of fire.", "bsb": "By the vastness of your trade, you were filled with violence, and you sinned. So I drove you in disgrace from the mountain of God, and I banished you, O guardian cherub, from among the fiery stones.", "asv": "By the abundance of thy traffic they filled the midst of thee with violence, and thou hast sinned: therefore have I cast thee as profane out of the mountain of God; and I have destroyed thee, O covering cherub, from the midst of the stones of fire.", "ylt": "By the abundance of thy merchandise They have filled thy midst with violence, And thou dost sin, And I thrust thee from the mount of God, And I destroy thee, O covering cherub, From the midst of the stones of fire.", "dra": "By the multitude of thy merchandise, thy inner parts were filled with iniquity, and thou hast sinned: and I cast thee out from the mountain of God, and destroyed thee, O covering cherub, out of the midst of the stones of fire.", "bbe": "Through all your trading you have become full of violent ways, and have done evil: so I sent you out shamed from the mountain of God; the winged one put an end to you from among the stones of fire.", "geneva": "By the multitude of thy marchandise, they haue filled the middes of thee with crueltie, and thou hast sinned: therefore I will cast thee as prophane out of the mountaine of God: and I will destroy thee, O couering Cherub from the mids of the stones of fire.", "wycliffe": "In the multitude of thi marchaundie thin ynnere thingis weren fillid of wickidnesse, and thou didist synne; and Y castide thee out of the hil of God, and, thou cherub hilynge fer, Y loste thee fro the myddis of stoonys set a fier.", "rotherham": "By the abundance of thy traffic, they filled thy midst with violence And thou didst sin,- So I cast thee as profane out of the mountain of God. And destroyed thee O covering cherub, from amid the stones of fire:", "darby": "By the abundance of thy traffic they filled the midst of thee with violence, and thou hast sinned; therefore have I cast thee as profane from the mountain ofGod, and have destroyed thee, O covering cherub, from the midst of the stones of fire.", "twenty": "", "jps": "By the multitude of thy traffic they filled the midst of thee with violence, and thou hast sinned; therefore have I cast thee as profane out of the mountain of G-d; and I have destroyed thee, O covering cherub, from the midst of the stones of fire.", "acv": "By the abundance of thy commerce they filled the midst of thee with violence, and thou have sinned. Therefore I have cast thee out of the mountain of God as profane, and I have destroyed thee, O covering cherub, from the midst of the stones of fire.", "anderson": "", "haweis": "", "noyes": "Through the abundance of thy merchandise thou art full of injustice; And thou hast sinned; Therefore I will cast thee as profane out of the mountain of God, And I will destroy thee, O covering cherub, from the midst of the stones of fire.", "webster": "By the multitude of thy merchandise they have filled the midst of thee with violence, and thou hast sinned: therefore I will cast thee as profane out of the mountain of God: and I will destroy thee, O covering cherub, from the midst of the stones of fire.", "vulgate": "in multitudine negotiationis tuae repleta sunt interiora tua iniquitate et peccasti et eieci te de monte Dei et perdidi te o cherub protegens de medio lapidum ignitorum;", "brenton": "Of the abundance of thy merchandise thou hast filled thy storehouses with iniquity, and hast sinned: therefore thou hast been cast down wounded from the mount of God, and the cherub has brought thee out of the midst of the stones of fire."}}, {"v": 17, "ref": "28:17", "o": "גָּבַ֤הּ לִבְּ/ךָ֙ בְּ/יָפְיֶ֔/ךָ שִׁחַ֥תָּ חָכְמָתְ/ךָ֖ עַל יִפְעָתֶ֑/ךָ עַל אֶ֣רֶץ הִשְׁלַכְתִּ֗י/ךָ לִ/פְנֵ֧י מְלָכִ֛ים נְתַתִּ֖י/ךָ לְ/רַ֥אֲוָה בָֽ/ךְ", "en": {"kjv": "Thine heart was lifted up because of thy beauty, thou hast corrupted thy wisdom by reason of thy brightness: I will cast thee to the ground, I will lay thee before kings, that they may behold thee.", "web": "Your heart was lifted up because of your beauty; you have corrupted your wisdom by reason of your brightness: I have cast you to the ground; I have laid you before kings, that they may see you.", "bsb": "Your heart grew proud of your beauty; you corrupted your wisdom because of your splendor; so I cast you to the earth; I made you a spectacle before kings.", "asv": "Thy heart was lifted up because of thy beauty; thou hast corrupted thy wisdom by reason of thy brightness: I have cast thee to the ground; I have laid thee before kings, that they may behold thee.", "ylt": "High hath been thy heart, because of thy beauty, Thou hast corrupted thy wisdom because of thy brightness, On the earth I have cast thee, Before kings I have set thee, to look on thee,", "dra": "And thy heart was lifted up with thy beauty: thou hast lost thy wisdom in thy beauty, I have cast thee to the ground: I have set thee before the face of kings, that they might behold thee.", "bbe": "Your heart was lifted up because you were beautiful, you made your wisdom evil through your sin: I have sent you down, even to the earth; I have made you low before kings, so that they may see you.", "geneva": "Thine heart was lifted vp because of thy beautie, and thou hast corrupted thy wisedome by reason of thy brightnes: I wil cast thee to ye grounde: I will lay thee before Kinges that they may beholde thee.", "wycliffe": "And thin herte was reisid in thi fairnesse, thou lostist thi wisdom in thi fairnesse. Y castide thee doun in to erthe, Y yaf thee bifore the face of kingis, that thei schulden se thee.", "rotherham": "Lofty, was thy heart in thy beauty, Thou didst corrupt thy wisdom, because of thy splendour,— Upon the earth, did I cast thee. Before kings, did I set thee That they might look at thee:", "darby": "Thy heart was lifted up because of thy beauty; thou hast corrupted thy wisdom by reason of thy brightness: I have cast thee to the ground, I have laid thee before kings, that they may behold thee.", "twenty": "", "jps": "Thy heart was lifted up because of thy beauty, thou hast corrupted thy wisdom by reason of thy brightness; I have cast thee to the ground, I have laid thee before kings, that they may gaze upon thee.", "acv": "Thy heart was lifted up because of thy beauty. Thou have corrupted thy wisdom because of thy brightness. I have cast thee to the ground. I have laid thee before kings, that they may behold thee.", "anderson": "", "haweis": "", "noyes": "Thy heart was lifted up because of thy beauty; Thou hast corrupted thy wisdom by reason of thy splendor; I will cast thee to the ground; I will give thee up to kings to be their gazing-stock.", "webster": "Thy heart was lifted up because of thy beauty, thou hast corrupted thy wisdom by reason of thy brightness: I will cast thee to the ground, I will lay thee before kings, that they may behold thee.", "vulgate": "elevatum est cor tuum in decore tuo perdidisti sapientiam tuam in decore tuo in terram proieci te ante faciem regum dedi te ut cernerent te;", "brenton": "Thy heart has been lifted up because of thy beauty; thy knowledge has been corrupted with thy beauty: because of the multitude of thy sins I have cast thee to the ground, I have caused thee to be put to open shame before kings."}}, {"v": 18, "ref": "28:18", "o": "מֵ/רֹ֣ב עֲוֺנֶ֗י/ךָ בְּ/עֶ֨וֶל֙ רְכֻלָּ֣תְ/ךָ֔ חִלַּ֖לְתָּ מִקְדָּשֶׁ֑י/ךָ וָֽ/אוֹצִא אֵ֤שׁ מִ/תּֽוֹכְ/ךָ֙ הִ֣יא אֲכָלַ֔תְ/ךָ וָ/אֶתֶּנְ/ךָ֤ לְ/אֵ֨פֶר֙ עַל הָ/אָ֔רֶץ לְ/עֵינֵ֖י כָּל רֹאֶֽי/ךָ", "en": {"kjv": "Thou hast defiled thy sanctuaries by the multitude of thine iniquities, by the iniquity of thy traffick; therefore will I bring forth a fire from the midst of thee, it shall devour thee, and I will bring thee to ashes upon the earth in the sight of all them that behold thee.", "web": "By the multitude of your iniquities, in the unrighteousness of your traffic, you have profaned your sanctuaries; therefore have I brought out a fire from your midst; it has devoured you, and I have turned you to ashes on the earth in the sight of all those who see you.", "bsb": "By the multitude of your iniquities and the dishonesty of your trading you have profaned your sanctuaries. So I made fire come from within you, and it consumed you. I reduced you to ashes on the ground in the eyes of all who saw you.", "asv": "By the multitude of thine iniquities, in the unrighteousness of thy traffic, thou hast profaned thy sanctuaries; therefore have I brought forth a fire from the midst of thee; it hath devoured thee, and I have turned thee to ashes upon the earth in the sight of all them that behold thee.", "ylt": "From the abundance of thy iniquity, By the perversity of thy traffic, Thou hast polluted thy sanctuaries, And I bring forth fire from thy midst, It hath devoured thee, And I make thee become ashes on the earth, Before the eyes of all beholding thee.", "dra": "Thou hast defiled thy sanctuaries by the multitude of thy iniquities, and by the iniquity of thy traffic: therefore I will bring forth a fire from the midst of thee, to devour thee, and I will make thee as ashes upon the earth in the sight of all that see thee.", "bbe": "By all your sin, even by your evil trading, you have made your holy places unclean; so I will make a fire come out from you, it will make a meal of you, and I will make you as dust on the earth before the eyes of all who see you.", "geneva": "Thou hast defiled thy sanctification by the multitude of thine iniquities, and by the iniquitie of thy marchandise: therefore wil I bring forth a fire from the mids of thee, which shall deuoure thee: and I wil bring thee to ashes vpon the earth, in the sight of all them that beholde thee.", "wycliffe": "In the multitude of thi wickidnessis, and in wickidnesse of thi marchaundie thou defoulidist thin halewyng; therfor Y schal brynge forth fier of the myddis of thee, that schal ete thee; and Y schal yyue thee in to aische on erthe, in the siyt of alle men seynge thee.", "rotherham": "Owing to the abounding of thine iniquities. In the perversity of thy traffic, Thou didst profane thy sanctuaries, Therefore brought I forth fire out of thy midst. the same devoured thee, And I turned thee to ashes on the ground, Before the eyes of all beholding thee:", "darby": "By the multitude of thine iniquities, by the unrighteousness of thy traffic, thou hast profaned thy sanctuaries: and I have brought forth a fire out of the midst of thee — it hath consumed thee; and I have brought thee to ashes upon the earth, in the sight of all them that behold thee.", "twenty": "", "jps": "By the multitude of thine iniquities, in the unrighteousness of thy traffic, thou hast profaned thy sanctuaries; therefore have I brought forth a fire from the midst of thee, it hath devoured thee, and I have turned thee to ashes upon the earth in the sight of all them that behold thee.", "acv": "By the multitude of thine iniquities, in the unrighteousness of thy commerce, thou have profaned thy sanctuaries. Therefore I have brought forth a fire from the midst of thee. It has devoured thee, and I have turned thee to ashes upon the earth in the sight of all those who behold thee.", "anderson": "", "haweis": "", "noyes": "By the multitude of thine iniquities, by the unrighteousness of thy traffic, Thou hast defiled thy sanctuaries. Therefore will I bring forth a fire from the midst of thee, which shall devour thee, And I will bring thee to ashes upon the earth, In the sight of all them that behold thee.", "webster": "Thou hast defiled thy sanctuaries by the multitude of thy iniquities, by the iniquity of thy traffick; therefore will I bring forth a fire from the midst of thee, it shall devour thee, and I will bring thee to ashes upon the earth in the sight of all them that behold thee.", "vulgate": "in multitudine iniquitatum tuarum et iniquitate negotiationis tuae polluisti sanctificationem tuam producam ergo ignem de medio tui qui comedat te et dabo te in cinerem super terram in conspectu omnium videntium te;", "brenton": "Because of the multitude of thy sins and the iniquities of thy merchandise, I have profaned thy sacred things; and I will bring fire out of the midst of thee, this shall devour thee; and I will make thee to be ashes upon thy land before all that see thee."}}, {"v": 19, "ref": "28:19", "o": "כָּל יוֹדְעֶ֨י/ךָ֙ בָּֽ/עַמִּ֔ים שָׁמְמ֖וּ עָלֶ֑י/ךָ בַּלָּה֣וֹת הָיִ֔יתָ וְ/אֵינְ/ךָ֖ עַד עוֹלָֽם", "en": {"kjv": "All they that know thee among the people shall be astonished at thee: thou shalt be a terror, and never shalt thou be any more.", "web": "All those who know you among the peoples shall be astonished at you: you have become a terror, and you shall nevermore have any being.", "bsb": "All the nations who know you are appalled over you. You have come to a horrible end and will be no more.’”", "asv": "All they that know thee among the peoples shall be astonished at thee: thou art become a terror, and thou shalt nevermore have any being.", "ylt": "All knowing thee among the peoples Have been astonished at thee, Wastes thou hast been, and thou art not--to the age.'", "dra": "All that shall see thee among the nations, shall be astonished at thee: thou art brought to nothing, and thou shalt never be any more.", "bbe": "All who have knowledge of you among the peoples will be overcome with wonder at you: you have become a thing of fear, and you will never be seen again.", "geneva": "All they that knowe thee among the people, shalbe astonished at thee: thou shalt be a terrour, and neuer shalt thou be any more.", "wycliffe": "Alle men that schulen se thee among hethene men, schulen be astonyed on thee; thou art maad nouyt, and thou schalt not be with outen ende.", "rotherham": "All that had known thee among the peoples were astounded over thee,— A terror, hast thou become, And, art not, Unto times age-abiding.", "darby": "All they that know thee among the peoples shall be amazed at thee: thou art become a terror, and thou shalt never be any more.", "twenty": "", "jps": "All they that know thee among the peoples shall be appalled at thee; thou art become a terror, and thou shalt never be any more.'", "acv": "All those who know thee among the peoples shall be astonished at thee. Thou have become a horror, and thou shall nevermore have any being.", "anderson": "", "haweis": "", "noyes": "All they that know thee among the nations shall be astonished at thee; Thou art become a desolation, and shalt exist no more forever.", "webster": "All they that know thee among the people shall be astonished at thee: thou shalt be a terror, and never [shalt] thou [be] any more.", "vulgate": "omnes qui viderint te in gentibus obstupescent super te nihili factus es et non eris in perpetuum;", "brenton": "And all that know thee among the nations shall groan over thee: thou art gone to destruction, and thou shalt not exist any more."}}, {"v": 20, "ref": "28:20", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Again the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Againe, the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Again the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 21, "ref": "28:21", "o": "בֶּן אָדָ֕ם שִׂ֥ים פָּנֶ֖י/ךָ אֶל צִיד֑וֹן וְ/הִנָּבֵ֖א עָלֶֽי/הָ", "en": {"kjv": "Son of man, set thy face against Zidon, and prophesy against it,", "web": "Son of man, set your face toward Sidon, and prophesy against it,", "bsb": "“Son of man, set your face against Sidon and prophesy against her.", "asv": "Son of man, set thy face toward Sidon, and prophesy against it,", "ylt": "`Son of man, set thy face unto Zidon, and prophesy concerning it;", "dra": "Son of man, set thy face against Sidon: and thou shalt prophesy of it,", "bbe": "Son of man, let your face be turned to Zidon, and be a prophet against it, and say,", "geneva": "Sonne of man, set thy face against Zidon, and prophesie against it,", "wycliffe": "and he seide, Thou, sone of man, sette thi face ayens Sidon, and thou schalt profesie of it;", "rotherham": "Son of man, Set thy face towards Zidon,— And prophesy over it;", "darby": "Son of man, set thy face towards Zidon, and prophesy against it,", "twenty": "", "jps": "'Son of man, set thy face toward Zidon, and prophesy against it,", "acv": "Son of man, set thy face toward Sidon, and prophesy against it,", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against Sidon, and prophesy against her,", "webster": "Son of man, set thy face against Zidon, and prophesy against it,", "vulgate": "fili hominis pone faciem tuam contra Sidonem et prophetabis de ea;", "brenton": "Son of man, set thy face against Sidon, and prophesy against it,"}}, {"v": 22, "ref": "28:22", "o": "וְ/אָמַרְתָּ֗ כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֤י עָלַ֨יִ/ךְ֙ צִיד֔וֹן וְ/נִכְבַּדְתִּ֖י בְּ/תוֹכֵ֑/ךְ וְֽ/יָדְע֞וּ כִּֽי אֲנִ֣י יְהוָ֗ה בַּ/עֲשׂ֥וֹתִ/י בָ֛/הּ שְׁפָטִ֖ים וְ/נִקְדַּ֥שְׁתִּי בָֽ/הּ", "en": {"kjv": "And say, Thus saith the Lord God; Behold, I am against thee, O Zidon; and I will be glorified in the midst of thee: and they shall know that I am the Lord, when I shall have executed judgments in her, and shall be sanctified in her.", "web": "and say, Thus says the Lord Yahweh: Behold, I am against you, Sidon; and I will be glorified in your midst; and they shall know that I am Yahweh, when I shall have executed judgments in her, and shall be sanctified in her.", "bsb": "And you are to declare that this is what the Lord GOD says: ‘Behold, I am against you, O Sidon, and I will be glorified within you. They will know that I am the LORD when I execute judgments against her and demonstrate My holiness through her.", "asv": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Sidon; and I will be glorified in the midst of thee; and they shall know that I am Jehovah, when I shall have executed judgments in her, and shall be sanctified in her.", "ylt": "and thou hast said: Thus said the Lord Jehovah: Lo, I am against thee, O Zidon, And I have been honoured in thy midst, And they have known that I am Jehovah, In My doing in her judgments, And I have been sanctified in her.", "dra": "And shalt say: Thus saith the Lord God: Behold I come against thee, Sidon, and I will be glorified in the midst of thee: and they shall know that I am the Lord, when I shall execute judgments in her, and shall be sanctified in her.", "bbe": "These are the words of the Lord: See, I am against you, O Zidon; and I will get glory for myself in you: and they will be certain that I am the Lord, when I send my punishments on her, and I will be seen to be holy in her.", "geneva": "And say, Thus saith the Lord God, Behold, I come against thee, O Zidon, and I will be glorified in the mids of thee: and they shall know that I am the Lord, when I shall haue executed iudgements in her, and shalbe sanctified in her.", "wycliffe": "and schalt seie, The Lord God seith these thingis, Lo! Y to thee, Sidon, and Y schal be glorified in the myddis of thee; and thei schulen wite, that Y am the Lord, whanne Y schal do domes in it, and Y schal be halewid ther ynne.", "rotherham": "and thou shalt say— Thus saith My Lord. Yahweh, Behold me! against thee, O Zidon, Therefore will I get myself glory in thy midst,— [And they shall know that, I, am Yahweh,] When I have executed against her judgments And hallowed myself in her.", "darby": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, Zidon, and I will be glorified in the midst of thee; and they shall know that I [am] Jehovah, when I shall have executed judgments in her, and shall be hallowed in her.", "twenty": "", "jps": "and say: Thus saith the L-rd GOD: Behold, I am against thee, O Zidon, and I will be glorified in the midst of thee; and they shall know that I am HaShem, when I shall have executed judgments in her, and shall be sanctified in her.", "acv": "and say, Thus says the lord Jehovah: Behold, I am against thee, O Sidon. And I will be glorified in the midst of thee. And they shall know that I am Jehovah, when I shall have executed judgments in her, and shall be sanctified in her.", "anderson": "", "haweis": "", "noyes": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Sidon, and I will be glorified in the midst of thee, and they shall know that I am Jehovah, when I execute judgments in her, and am sanctified in her.", "webster": "And say, Thus saith the Lord GOD; Behold, I [am] against thee, O Zidon; and I will be glorified in the midst of thee: and they shall know that I [am] the LORD, when I shall have executed judgments in her, and shall be sanctified in her.", "vulgate": "et dices haec dicit Dominus Deus ecce ego ad te Sidon et glorificabor in medio tui et scient quia ego Dominus cum fecero in ea iudicia et sanctificatus fuero in ea;", "brenton": "and say, Thus saith the Lord; Behold, I am against thee, O Sidon; and I will be glorified in thee; and thou shalt know that I am the Lord, when I have wrought judgments in thee, and I will be sanctified in thee."}}, {"v": 23, "ref": "28:23", "o": "וְ/שִׁלַּחְתִּי בָ֞/הּ דֶּ֤בֶר וָ/דָם֙ בְּ/ח֣וּצוֹתֶ֔י/הָ וְ/נִפְלַ֤ל חָלָל֙ בְּ/תוֹכָ֔/הּ בְּ/חֶ֥רֶב עָלֶ֖י/הָ מִ/סָּבִ֑יב וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "For I will send into her pestilence, and blood into her streets; and the wounded shall be judged in the midst of her by the sword upon her on every side; and they shall know that I am the Lord.", "web": "For I will send pestilence into her, and blood into her streets; and the wounded shall fall in the midst of her, with the sword on her on every side; and they shall know that I am Yahweh.", "bsb": "I will send a plague against her and shed blood in her streets; the slain will fall within her, while the sword is against her on every side. Then they will know that I am the LORD.", "asv": "For I will send pestilence into her, and blood into her streets; and the wounded shall fall in the midst of her, with the sword upon her on every side; and they shall know that I am Jehovah.", "ylt": "And I have sent into her pestilence, And blood into her out-places, The wounded hath been judged in her midst, By the sword upon her round about, And they have known that I am Jehovah.", "dra": "And I will send into her pestilence, and blood in her streets: and they shall fall being slain by the sword on all sides in the midst thereof: and they shall know that I am the Lord.", "bbe": "And I will send on her disease and blood in her streets; and the wounded will be falling in the middle of her, and the sword will be against her on every side; and they will be certain that I am the Lord.", "geneva": "For I wil send into her pestilence, and blood into her streetes, and the slaine shall fall in the middes of her: the enemie shall come against her with the sword on euery side, and they shall know that I am the Lord.", "wycliffe": "And Y schal sende pestilence in to it, and blood in the stretis therof, and slayn men bi swerd schulen falle doun in the myddis therof bi cumpas; and thei schulen wite, that Y am the Lord God.", "rotherham": "So then I will send against her, pestilence and blood in her streets, And the wounded shall fall in her midst by the sword upon her from every side,— And they shall know that, I, am Yahweh.", "darby": "And I will send into her the pestilence, and blood in her streets; and the wounded shall fall in the midst of her, by the sword upon her on every side: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "For I will send into her pestilence and blood in her streets; and the wounded shall fall in the midst of her by the sword upon her on every side; and they shall know that I am HaShem.", "acv": "For I will send pestilence into her, and blood into her streets. And the wounded shall fall in the midst of her, with the sword upon her on every side. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "I will send upon her pestilence, and blood into her streets, and the wounded shall fall in the midst of her by the sword which is against her on every side; and they shall know that I am Jehovah.", "webster": "For I will send into her pestilence, and blood into her streets; and the wounded shall be judged in the midst of her by the sword upon her on every side; and they shall know that I [am] the LORD.", "vulgate": "et inmittam ei pestilentiam et sanguinem in plateis eius et corruent interfecti in medio eius gladio per circuitum et scient quia ego Dominus;", "brenton": "Blood and death shall be in thy streets; and men wounded with swords shall fall in thee and on every side of thee; and they shall know that I am the Lord."}}, {"v": 24, "ref": "28:24", "o": "וְ/לֹֽא יִהְיֶ֨ה ע֜וֹד לְ/בֵ֣ית יִשְׂרָאֵ֗ל סִלּ֤וֹן מַמְאִיר֙ וְ/ק֣וֹץ מַכְאִ֔ב מִ/כֹּל֙ סְבִ֣יבֹתָ֔/ם הַ/שָּׁאטִ֖ים אוֹתָ֑/ם וְ/יָ֣דְע֔וּ כִּ֥י אֲנִ֖י אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And there shall be no more a pricking brier unto the house of Israel, nor any grieving thorn of all that are round about them, that despised them; and they shall know that I am the Lord God.", "web": "There shall be no more a pricking brier to the house of Israel, nor a hurting thorn of any that are around them, that scorned them; and they shall know that I am the Lord Yahweh.", "bsb": "For the people of Israel will no longer face a pricking brier or a painful thorn from all around them who treat them with contempt. Then they will know that I am the Lord GOD.’", "asv": "And there shall be no more a pricking brier unto the house of Israel, nor a hurting thorn of any that are round about them, that did despite unto them; and they shall know that I am the Lord Jehovah.", "ylt": "And there is no more to the house of Israel A pricking brier, and paining thorn, Of all round about them--despising them, And they have known that I am the Lord Jehovah.", "dra": "And the house of Israel shall have no more a stumblingblock of bitterness, nor a thorn causing pain on every side round about them, of them that are against them: and they shall know that I am the Lord God.", "bbe": "And there will no longer be a plant with sharp points wounding the children of Israel, or a thorn troubling them among any who are round about them, who put shame on them; and they will be certain that I am the Lord.", "geneva": "And they shalbe no more a pricking thorne vnto the house of Israel, nor any grieuous thorne of all that are round about them, and despised them, and they shall knowe that I am the Lord God.", "wycliffe": "And there schal no more be an hirtyng of bitternesse to the hous of Israel, and a thorn bryngynge in sorewe on ech side bi the cumpas of hem that ben aduersaries to hem; and thei schulen wite, that Y am the Lord God.", "rotherham": "And the house of Israel shall no more have a stinging prickle or a wounding thorn, of any round about them who used to despise them,- So shall they know that, I, am The Lord Yahweh.", "darby": "And there shall be no more a wounding sting for the house of Israel, nor any grieving thorn, among all that were round about them, that despised them: and they shall know that I [am] the Lord Jehovah.", "twenty": "", "jps": "And there shall be no more a pricking brier unto the house of Israel, nor a piercing thorn of any that are round about them, that did have them in disdain; and they shall know that I am the L-rd GOD.", "acv": "And there shall no more be a pricking brier to the house of Israel, nor a hurting thorn of any who are round about them, who did spite to them. And they shall know that I am the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And there shall be no more to the house of Israel a pricking brier, or a grieving thorn of all that are round about them, that despised them; and they shall know that I am the Lord Jehovah.", "webster": "And there shall be no more a pricking brier to the house of Israel, nor [any] grieving thorn of all [that are] around them, that despised them; and they shall know that I [am] the Lord GOD.", "vulgate": "et non erit ultra domui Israhel offendiculum amaritudinis et spina dolorem inferens undique per circuitum eorum qui adversantur eis et scient quia ego Dominus Deus;", "brenton": "And there shall no more be in the house of Israel a thorn of bitterness and a pricking briar proceeding from them that are round about them, who dishonoured them; and they shall know that I am the Lord."}}, {"v": 25, "ref": "28:25", "o": "כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ בְּ/קַבְּצִ֣/י אֶת בֵּ֣ית יִשְׂרָאֵ֗ל מִן הָֽ/עַמִּים֙ אֲשֶׁ֣ר נָפֹ֣צוּ בָ֔/ם וְ/נִקְדַּ֥שְׁתִּי בָ֖/ם לְ/עֵינֵ֣י הַ/גּוֹיִ֑ם וְ/יָֽשְׁבוּ֙ עַל אַדְמָתָ֔/ם אֲשֶׁ֥ר נָתַ֖תִּי לְ/עַבְדִּ֥/י לְ/יַעֲקֹֽב", "en": {"kjv": "Thus saith the Lord God; When I shall have gathered the house of Israel from the people among whom they are scattered, and shall be sanctified in them in the sight of the heathen, then shall they dwell in their land that I have given to my servant Jacob.", "web": "Thus says the Lord Yahweh: When I shall have gathered the house of Israel from the peoples among whom they are scattered, and shall be sanctified in them in the sight of the nations, then shall they dwell in their own land which I gave to my servant Jacob.", "bsb": "This is what the Lord GOD says: ‘When I gather the house of Israel from the peoples among whom they have been scattered, I will show Myself holy among them in the sight of the nations. Then they will dwell in their own land, which I have given to My servant Jacob.", "asv": "Thus saith the Lord Jehovah: When I shall have gathered the house of Israel from the peoples among whom they are scattered, and shall be sanctified in them in the sight of the nations, then shall they dwell in their own land which I gave to my servant Jacob.", "ylt": "Thus said the Lord Jehovah: In My gathering the house of Israel, Out of the peoples among whom they were scattered, I have been sanctified in them, Before the eyes of the nations, And they have dwelt on their ground, That I gave to My servant, to Jacob,", "dra": "Thus saith the Lord God: When I shall have gathered together the house of Israel out of the people among whom they are scattered: I will be sanctified in them before the Gentiles: and they shall dwell in their own land, which I gave to my servant Jacob.", "bbe": "This is what the Lord has said: When I have got together the children of Israel from the peoples among whom they are wandering, and have been made holy among them before the eyes of the nations, then they will have rest in the land which is theirs, which I gave to my servant Jacob", "geneva": "Thus saith the Lord God, When I shall haue gathered the house of Israel from the people where they are scattered, and shalbe sanctified in them in the sight of the heathen, then shall they dwel in the land, that I haue giuen to my seruant Iaakob.", "wycliffe": "The Lord God seith these thingis, Whanne Y schal gadere togidere the hous of Israel fro puplis, among whiche thei ben scaterid, Y schal be halewid in hem bifor hethene men. And thei schulen dwelle in her lond, which Y yaf to my seruaunt Jacob.", "rotherham": "Thus saith My Lord, Yahweh, When I gather together the house of Israel, from the midst of the peoples among whom they have been scattered, and shall hallow myself in them before the eyes of the nations Then shall they dwell upon their own soil, which I gave to my servant—to Jacob:", "darby": "Thus saith the Lord Jehovah: When I shall have gathered the house of Israel from the peoples among whom they are scattered, and shall be hallowed in them in the sight of the nations, then shall they dwell in their land which I have given to my servant Jacob.", "twenty": "", "jps": "Thus saith the L-rd GOD: When I shall have gathered the house of Israel from the peoples among whom they are scattered, and shall be sanctified in them in the sight of the nations, then shall they dwell in their own land which I gave to My servant Jacob.", "acv": "Thus says the lord Jehovah: When I shall have gathered the house of Israel from the peoples among whom they are scattered, and shall be sanctified in them in the sight of the nations, then they shall dwell in their own land which I gave to my servant Jacob.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: When I shall gather the house of Israel from the nations among which they are scattered, then shall I be sanctified through them in the sight of the nations, and they shall dwell in the land which I gave to my servant Jacob.", "webster": "Thus saith the Lord GOD; When I shall have gathered the house of Israel from the people among whom they are scattered, and shall be sanctified in them in the sight of the heathen, then shall they dwell in their land that I have given to my servant Jacob.", "vulgate": "haec dicit Dominus Deus quando congregavero domum Israhel de populis in quibus dispersi sunt sanctificabor in eis coram gentibus et habitabunt in terra sua quam dedi servo meo Iacob;", "brenton": "Thus saith the Lord God; I will also gather Israel from the nations, among whom they have been scattered, and I will be sanctified among them, and before the peoples and nations: and they shall dwell upon their land, which I gave to my servant Jacob."}}, {"v": 26, "ref": "28:26", "o": "וְ/יָשְׁב֣וּ עָלֶי/הָ֮ לָ/בֶטַח֒ וּ/בָנ֤וּ בָתִּים֙ וְ/נָטְע֣וּ כְרָמִ֔ים וְ/יָשְׁב֖וּ לָ/בֶ֑טַח בַּ/עֲשׂוֹתִ֣/י שְׁפָטִ֗ים בְּ/כֹ֨ל הַ/שָּׁאטִ֤ים אֹתָ/ם֙ מִ/סְּבִ֣יבוֹתָ֔/ם וְ/יָ֣דְע֔וּ כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹהֵי/הֶֽם", "en": {"kjv": "And they shall dwell safely therein, and shall build houses, and plant vineyards; yea, they shall dwell with confidence, when I have executed judgments upon all those that despise them round about them; and they shall know that I am the Lord their God.", "web": "They shall dwell securely therein; yes, they shall build houses, and plant vineyards, and shall dwell securely, when I have executed judgments on all those who do them despite all around them; and they shall know that I am Yahweh their God.", "bsb": "And there they will dwell securely, build houses, and plant vineyards. They will dwell securely when I execute judgments against all those around them who treat them with contempt. Then they will know that I am the LORD their God.’”", "asv": "And they shall dwell securely therein; yea, they shall build houses, and plant vineyards, and shall dwell securely, when I have executed judgments upon all those that do them despite round about them; and they shall know that I am Jehovah their God.", "ylt": "And they have dwelt on it confidently, And builded houses, and planted vineyards, And dwelt confidently--in My doing judgments, On all those despising them round about, And they have known that I, Jehovah, am their God!'", "dra": "And they shall dwell therein secure, and they shall build houses, and shall plant vineyards, and shall dwell with confidence, when I shall have executed judgments upon all that are their enemies round about: and they shall know that I am the Lord their God.", "bbe": "And they will be safe there, building houses and planting vine-gardens and living without fear; when I have sent my punishments on all those who put shame on them round about them; and they will be certain that I am the Lord their God.", "geneva": "And they shall dwell safely therein, and shall builde houses, and plant vineyards: yea, they shall dwell safely, when I haue executed iudgements vpon al round about them that despise them, and they shall knowe that I am the Lord their God.", "wycliffe": "And thei schulen dwelle sikir ther ynne, and thei schulen bilde housis, and thei schulen plaunte vynes, and thei schulen dwelle tristili, whanne Y schal make domes in alle men that ben aduersaries to hem bi cumpas; and thei schulen wite, that Y am the Lord God of hem.", "rotherham": "Yea they shall dwell thereupon securely, Yea shall build houses, and plant vineyards, and dwell securely,— When I have executed judgments on all that despised them on every side of them, So shall they know that, I, Yahweh am their God", "darby": "They shall dwell in it in safety, and shall build houses and plant vineyards; and they shall dwell in safety, when I have executed judgments upon all those that despised them round about them: and they shall know that I [am] Jehovah theirGod.", "twenty": "", "jps": "And they shall dwell safely therein, and shall build houses, and plant vineyards; yea, they shall dwell safely; when I have executed judgments upon all those that have them in disdain round about them; and they shall know that I am HaShem their G-d.'", "acv": "And they shall dwell securely therein. Yea, they shall build houses, and plant vineyards, and shall dwell securely, when I have executed judgments upon all those who do them spite round about them. And they shall know that I am Jehovah their God.", "anderson": "", "haweis": "", "noyes": "They shall dwell therein securely, and shall build houses, and plant vineyards, yea, they shall dwell securely when I have executed judgments on all that despised them round about; and they shall know that I am Jehovah, their God.", "webster": "And they shall dwell safely therein, and shall build houses, and plant vineyards; yes, they shall dwell with confidence, when I have executed judgments upon all those that despise them around them; and they shall know that I [am] the LORD their God.", "vulgate": "et habitabunt in ea securi et aedificabunt domos plantabuntque vineas et habitabunt confidenter cum fecero iudicia in omnibus qui adversantur eis per circuitum et scient quia ego Dominus Deus eorum;", "brenton": "Yea, they shall dwell upon it safely, and they shall build houses, and plant vineyards, and dwell securely, when I shall execute judgment on all that have dishonoured them, even on those that are round about them; and they shall know that I am the Lord their God, and the God of their fathers."}}]}, {"c": 29, "verses": [{"v": 1, "ref": "29:1", "o": "בַּ/שָּׁנָה֙ הָ/עֲשִׂירִ֔ית בָּ/עֲשִׂרִ֕י בִּ/שְׁנֵ֥ים עָשָׂ֖ר לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "In the tenth year, in the tenth month, in the twelfth day of the month, the word of the Lord came unto me, saying,", "web": "In the tenth year, in the tenth month, on the twelfth day of the month, Yahweh’s word came to me, saying,", "bsb": "In the tenth year, on the twelfth day of the tenth month, the word of the LORD came to me, saying,", "asv": "In the tenth year, in the tenthmonth, in the twelfth day of the month, the word of Jehovah came unto me, saying,", "ylt": "In the tenth year, in the tenth month , in the twelfth of the month, hath a word of Jehovah been unto me, saying,", "dra": "In the tenth year, the tenth month, the eleventh day of the month, the word of the Lord came to me, saying:", "bbe": "In the tenth year, in the tenth month, on the twelfth day of the month, the word of the Lord came to me, saying,", "geneva": "In the tenth yeere, and in the tenth moneth in the twelfth day of the moneth, the word of the Lord came vnto me, saying,", "wycliffe": "In the tenthe yeer, in the tweluethe monethe, in the firste dai of the monethe, the word of the Lord was maad to me, and he seide,", "rotherham": "In the tenth year, in the tenth month, on the twelfth of the month, came the word of Yahweh unto me, saying:", "darby": "In the tenth year, in the tenth [month], on the twelfth of the month, the word of Jehovah came unto me, saying,", "twenty": "", "jps": "In the tenth year, in the tenth month, in the twelfth day of the month, the word of HaShem came unto me, saying:", "acv": "In the tenth year, in the tenth month, in the twelfth day of the month, the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "In the tenth year, in the tenth month, in the twelfth day of the month, the word of Jehovah came to me, saying:", "webster": "In the tenth year, in the tenth [month], in the twelfth [day] of the month, the word of the LORD came to me, saying,", "vulgate": "in anno decimo in decimo mense undecima mensis factum est verbum Domini ad me dicens;", "brenton": "In the twelfth year, in the tenth month, on the first day of the month, the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "29:2", "o": "בֶּן אָדָ֕ם שִׂ֣ים פָּנֶ֔י/ךָ עַל פַּרְעֹ֖ה מֶ֣לֶךְ מִצְרָ֑יִם וְ/הִנָּבֵ֣א עָלָ֔י/ו וְ/עַל מִצְרַ֖יִם כֻּלָּֽ/הּ", "en": {"kjv": "Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt:", "web": "“Son of man, set your face against Pharaoh king of Egypt, and prophesy against him and against all Egypt.", "bsb": "“Son of man, set your face against Pharaoh king of Egypt and prophesy against him and against all Egypt.", "asv": "Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt;", "ylt": "`Son of man, set thy face against Pharaoh king of Egypt, and prophesy concerning him, and concerning Egypt--all of it.", "dra": "Son of man, set thy face against Pharao king of Egypt: and thou shalt prophesy of him, and of all Egypt:", "bbe": "Son of man, let your face be turned against Pharaoh, king of Egypt, and be a prophet against him and against all Egypt:", "geneva": "Sonne of man, set thy face against Pharaoh the King of Egypt, and prophecie against him, and against all Egypt.", "wycliffe": "Thou, sone of man, sette thi face ayens Farao, king of Egipt; and thou schalt profesie of hym, and of al Egipt.", "rotherham": "Son of man, Set thy face against Pharaoh, king of Egypt, And prophesy against him, and against Egypt all of it:", "darby": "Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against the whole of Egypt;", "twenty": "", "jps": "'Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt;", "acv": "Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against Pharaoh, the king of Egypt, and prophesy against him, and against all Egypt;", "webster": "Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt:", "vulgate": "fili hominis pone faciem tuam contra Pharaonem regem Aegypti et prophetabis de eo et de Aegypto universa;", "brenton": "Son of man, set thy face against Pharao king of Egypt, and prophesy against him, and against the whole of Egypt:"}}, {"v": 3, "ref": "29:3", "o": "דַּבֵּ֨ר וְ/אָמַרְתָּ֜ כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הִנְ/נִ֤י עָלֶ֨י/ךָ֙ פַּרְעֹ֣ה מֶֽלֶךְ מִצְרַ֔יִם הַ/תַּנִּים֙ הַ/גָּד֔וֹל הָ/רֹבֵ֖ץ בְּ/ת֣וֹךְ יְאֹרָ֑י/ו אֲשֶׁ֥ר אָמַ֛ר לִ֥/י יְאֹרִ֖/י וַ/אֲנִ֥י עֲשִׂיתִֽ/נִי", "en": {"kjv": "Speak, and say, Thus saith the Lord God; Behold, I am against thee, Pharaoh king of Egypt, the great dragon that lieth in the midst of his rivers, which hath said, My river is mine own, and I have made it for myself.", "web": "Speak and say, ‘Thus says the Lord Yahweh: “Behold, I am against you, Pharaoh king of Egypt, the great monster that lies in the midst of his rivers, that has said, ‘My river is my own, and I have made it for myself.’", "bsb": "Speak to him and tell him that this is what the Lord GOD says: Behold, I am against you, O Pharaoh king of Egypt, O great monster who lies among his rivers, who says, ‘The Nile is mine; I made it myself.’", "asv": "speak, and say, Thus saith the Lord Jehovah: Behold, I am against thee, Pharaoh king of Egypt, the great monster that lieth in the midst of his rivers, that hath said, My river is mine own, and I have made it for myself.", "ylt": "Speak, and thou hast said: Thus said the Lord Jehovah: Lo, I am against thee, Pharaoh king of Egypt! The great dragon that is crouching in the midst of his floods, Who hath said, My flood is my own, And I--I have made it for myself.", "dra": "Speak, and say: Thus saith the Lord God: Behold, I come against thee, Pharao king of Egypt, thou great dragon that liest in the midst of thy rivers, and sayest: The river is mine, and I made myself.", "bbe": "Say to them, These are the words of the Lord: See, I am against you, Pharaoh, king of Egypt, the great river-beast stretched out among his Nile streams, who has said, The Nile is mine, and I have made it for myself.", "geneva": "Speake, and say, Thus sayth the Lord God, Beholde, I come against thee, Pharaoh King of Egypt, the great dragon, that lieth in the middes of his riuers, which hath saide, The riuer is mine, and I haue made it for my selfe.", "wycliffe": "Speke thou, and thou schalt seie, The Lord God seith these thingis, Lo! Y to thee, thou Farao, kyng of Egipt, thou grete dragoun, that liggist in the myddis of thi floodis, and seist, The flood is myn, and Y made mysilf.", "rotherham": "Speak, and thou shalt say— Thus, saith My Lord Yahweh Behold me! against thee O Pharaoh king of Egypt, The great Crocodile that lieth along in the midst of his rivers: Who saith— My river is, mine own, Since I myself made it me!", "darby": "speak, and say, Thus saith the Lord Jehovah: Behold, I am against thee, Pharaoh king of Egypt, the great monster that lieth in the midst of his rivers, which saith, My river is mine own, and I made it for myself.", "twenty": "", "jps": "speak, and say: Thus saith the L-rd GOD: behold, I am against thee, Pharaoh King of Egypt, the great dragon that lieth in the midst of his rivers, that hath said: My river is mine own, and I have made it for myself.", "acv": "Speak, and say, Thus says the lord Jehovah: Behold, I am against thee, Pharaoh king of Egypt, the great monster that lies in the midst of his rivers, that has said, My river is my own, and I have made it for myself.", "anderson": "", "haweis": "", "noyes": "Speak, and say, Thus saith the Lord Jehovah: Behold, I am against thee, Pharaoh, king of Egypt, thou great dragon, that liest in the midst of thy rivers, and sayest, \"My river is my own, and I have made it for myself.\"", "webster": "Speak, and say, Thus saith the Lord GOD; Behold, I [am] against thee, Pharaoh king of Egypt, the great dragon that lieth in the midst of his rivers, which hath said, My river [is] my own, and I have made [it] for myself.", "vulgate": "loquere et dices haec dicit Dominus Deus ecce ego ad te Pharao rex Aegypti draco magne qui cubas in medio fluminum tuorum et dicis meus est fluvius et ego feci memet ipsum;", "brenton": "and say, Thus saith the Lord; Behold, I am against Pharao, the great dragon that lies in the midst of his rivers, that says, The rivers are mine, and I made them."}}, {"v": 4, "ref": "29:4", "o": "וְ/נָתַתִּ֤י חחיים חַחִים֙ בִּ/לְחָיֶ֔י/ךָ וְ/הִדְבַּקְתִּ֥י דְגַת יְאֹרֶ֖י/ךָ בְּ/קַשְׂקְשֹׂתֶ֑י/ךָ וְ/הַעֲלִיתִ֨י/ךָ֙ מִ/תּ֣וֹךְ יְאֹרֶ֔י/ךָ וְ/אֵת֙ כָּל דְּגַ֣ת יְאֹרֶ֔י/ךָ בְּ/קַשְׂקְשֹׂתֶ֖י/ךָ תִּדְבָּֽק", "en": {"kjv": "But I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick unto thy scales, and I will bring thee up out of the midst of thy rivers, and all the fish of thy rivers shall stick unto thy scales.", "web": "I will put hooks in your jaws, and I will make the fish of your rivers stick to your scales; and I will bring you up out of the midst of your rivers, with all the fish of your rivers which stick to your scales.", "bsb": "But I will put hooks in your jaws and cause the fish of your streams to cling to your scales. I will haul you up out of your rivers, and all the fish of your streams will cling to your scales.", "asv": "And I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick unto thy scales; and I will bring thee up out of the midst of thy rivers, with all the fish of thy rivers which stick unto thy scales.", "ylt": "And I have put hooks in thy jaws, And I have caused the fish of thy floods to cleave to thy scales, And I have caused thee to come up from the midst of thy floods, And every fish of thy floods to thy scales doth cleave.", "dra": "But I will put a bridle in thy jaws: and I will cause the fish of thy rivers to stick to thy scales: and I will draw thee out of the midst of thy rivers, and all thy fish shall stick to thy scales.", "bbe": "And I will put hooks in your mouth, and the fish of your streams will be hanging from your skin; and I will make you come up out of your streams, with all the fish of your streams hanging from your skin.", "geneva": "But I will put hookes in thy chawes, and I will cause the fish of thy riuers to sticke vnto thy scales, and I will drawe thee out of the middes of thy riuers, and all the fishe of thy riuers shall sticke vnto thy scales.", "wycliffe": "And Y schal sette a bridil in thi chekis, and Y schal glue the fischis of thi floodis to thi scalis; and Y schal drawe thee out of the myddis of thi floodis, and alle thi fischis schulen cleue to thi scalis.", "rotherham": "Therefore will I put hooks in thy jaws, And cause the fish of thy rivers to stick fast in thy scales,- And will bring thee up out of the midst of thy rivers, And, all the fish of thy rivers, to thy scales, shall stick fast;", "darby": "And I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick unto thy scales, and I will bring thee up out of the midst of thy rivers, and all the fish of thy rivers shall stick unto thy scales;", "twenty": "", "jps": "And I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick unto thy scales; and I will bring thee up out of the midst of thy rivers, and all the fish of thy rivers shall stick unto thy scales.", "acv": "And I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick to thy scales, and I will bring thee up out of the midst of thy rivers, with all the fish of thy rivers which stick to thy scales.", "anderson": "", "haweis": "", "noyes": "And I will put hooks in thy jaws, and I will cause the fish of thy rivers to cleave to thy scales, and I will draw thee forth from the midst of thy rivers, and all the fish of thy rivers which cleave to thy scales.", "webster": "But I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick to thy scales, and I will bring thee out of the midst of thy rivers, and all the fish of thy rivers shall stick to thy scales.", "vulgate": "et ponam frenum in maxillis tuis et adglutinabo pisces fluminum tuorum squamis tuis et extraham te de medio fluminum tuorum et universi pisces tui squamis tuis adherebunt;", "brenton": "And I will put hooks in thy jaws, and I will cause the fish of thy river to stick to thy sides, and I will bring thee up out of the midst of thy river:"}}, {"v": 5, "ref": "29:5", "o": "וּ/נְטַשְׁתִּ֣י/ךָ הַ/מִּדְבָּ֗רָ/ה אוֹתְ/ךָ֙ וְ/אֵת֙ כָּל דְּגַ֣ת יְאֹרֶ֔י/ךָ עַל פְּנֵ֤י הַ/שָּׂדֶה֙ תִּפּ֔וֹל לֹ֥א תֵאָסֵ֖ף וְ/לֹ֣א תִקָּבֵ֑ץ לְ/חַיַּ֥ת הָ/אָ֛רֶץ וּ/לְ/ע֥וֹף הַ/שָּׁמַ֖יִם נְתַתִּ֥י/ךָ לְ/אָכְלָֽה", "en": {"kjv": "And I will leave thee thrown into the wilderness, thee and all the fish of thy rivers: thou shalt fall upon the open fields; thou shalt not be brought together, nor gathered: I have given thee for meat to the beasts of the field and to the fowls of the heaven.", "web": "I’ll cast you out into the wilderness, you and all the fish of your rivers. You’ll fall on the open field. You won’t be brought together, nor gathered. I have given you for food to the animals of the earth and to the birds of the sky.", "bsb": "I will leave you in the desert, you and all the fish of your streams. You will fall on the open field and will not be taken away or gathered for burial. I have given you as food to the beasts of the earth and the birds of the air.", "asv": "And I will cast thee forth into the wilderness, thee and all the fish of thy rivers: thou shalt fall upon the open field; thou shalt not be brought together, nor gathered; I have given thee for food to the beasts of the earth and to the birds of the heavens.", "ylt": "And I have left thee in the wilderness, Thou and every fish of thy floods, On the face of the field thou dost fall, Thou art not gathered nor assembled, To the beast of the earth and to the fowl of the heavens I have given thee for food.", "dra": "And I will cast thee forth into the desert, and all the fish of thy river: thou shalt fall upon the face of the earth, thou shalt not be taken up, nor gathered together: I have given thee for meat to the beasts of the earth, and to the fowls of the air.", "bbe": "And I will let you be in the waste land, you and all the fish of your streams: you will go down on the face of the land; you will not be taken up or put to rest in the earth; I have given you for food to the beasts of the field and the birds of the heaven.", "geneva": "And I will leaue thee in the wildernes, both thee and al the fish of thy riuers: thou shalt fal vpon ye open field: thou shalt not be brought together, nor gathered: for I haue giue thee for meat to the beasts of the field, and to the foules of heauen.", "wycliffe": "And Y schal caste thee forth in to desert, and alle the fischis of thi flood; on the face of erthe thou schalt falle doun, thou schalt not be gaderid, nethir schalt be gaderid togidere; to the beestis of erthe, and to the volatilis of the eir Y yaf thee to be deuourid.", "rotherham": "And I will stretch thee out towards the desert, Thee and all the fish of thy rivers, On the face of the field, shalt thou lie Thou shalt not be carried away nor shalt thou be gathered, To the wild beast of the earth and to the bird of the heavens, have I given thee for food.", "darby": "and I will cast thee into the wilderness, thee and all the fish of thy rivers: thou shalt fall upon the open field; thou shalt not be brought together nor gathered: I will give thee for meat to the beasts of the earth and to the fowl of the heavens.", "twenty": "", "jps": "And I will cast thee into the wilderness, thee and all the fish of thy rivers; thou shalt fall upon the open field; thou shalt not be brought together, nor gathered; to the beasts of the earth and to the fowls of the heaven have I given thee for food.", "acv": "And I will cast thee forth into the wilderness, thee and all the fish of thy rivers. Thou shall fall upon the open field. Thou shall not be brought together, nor gathered. I have given thee for food to the beasts of the earth and to the birds of the heavens.", "anderson": "", "haweis": "", "noyes": "And I will cast thee into the desert, thee and all the fish of thy rivers; thou shalt fall upon the open fields; thou shalt not be brought together, nor gathered; to the beasts of the field and the birds of heaven I have given thee for food.", "webster": "And I will leave thee [thrown] into the wilderness, thee and all the fish of thy rivers: thou shalt fall upon the open fields; thou shalt not be brought together, nor gathered: I have given thee for food to the beasts of the field and to the fowls of heaven.", "vulgate": "et proiciam te in desertum et omnes pisces fluminis tui super faciem terrae cades non colligeris neque congregaberis bestiis terrae et volatilibus caeli dedi te ad devorandum;", "brenton": "and I will quickly cast down thee and all the fish of thy river: thou shalt fall on the face of the plain, and shalt by no means be gathered, and shalt not be brought together: I have given thee for food to the wild beasts of the earth and to the fowls of the sky."}}, {"v": 6, "ref": "29:6", "o": "וְ/יָֽדְעוּ֙ כָּל יֹשְׁבֵ֣י מִצְרַ֔יִם כִּ֖י אֲנִ֣י יְהוָ֑ה יַ֧עַן הֱיוֹתָ֛/ם מִשְׁעֶ֥נֶת קָנֶ֖ה לְ/בֵ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "And all the inhabitants of Egypt shall know that I am the Lord, because they have been a staff of reed to the house of Israel.", "web": "All the inhabitants of Egypt will know that I am Yahweh, because they have been a staff of reed to the house of Israel.", "bsb": "Then all the people of Egypt will know that I am the LORD. For you were only a staff of reeds to the house of Israel.", "asv": "And all the inhabitants of Egypt shall know that I am Jehovah, because they have been a staff of reed to the house of Israel.", "ylt": "And known have all inhabitants of Egypt That I am Jehovah, Because of their being a staff of reed to the house of Israel.", "dra": "And all the inhabitants of Egypt shall know that I am the Lord: because thou hast been a staff of a reed to the house of Israel.", "bbe": "And it will be clear to all the people of Egypt that I am the Lord, because you have been a false support to the children of Israel.", "geneva": "And al the inhabitants of Egypt shall know that I am the Lord, because they haue ben a staffe of reede to the house of Israel.", "wycliffe": "And alle the dwelleris of Egipt schulen knowe, that Y am the Lord. For that that thou were a staf of rehed to the hous of Israel, whanne thei token thee with hond,", "rotherham": "So shall all the inhabitants of Egypt know that I, am Yahweh, Because they were a staff of reed to the house of Israel:", "darby": "And all the inhabitants of Egypt shall know that I [am] Jehovah, because they have been a staff of reed to the house of Israel.", "twenty": "", "jps": "And all the inhabitants of Egypt shall know that I am HaShem, because they have been a staff of reed to the house of Israel.", "acv": "And all the inhabitants of Egypt shall know that I am Jehovah, because they have been a staff of reed to the house of Israel.", "anderson": "", "haweis": "", "noyes": "And all the inhabitants of Egypt shall know that I am Jehovah; because they have been a staff of reed to the house of Israel.", "webster": "And all the inhabitants of Egypt shall know that I [am] the LORD, because they have been a staff of reed to the house of Israel.", "vulgate": "et scient omnes habitatores Aegypti quia ego Dominus pro eo quod fuisti baculus harundineus domui Israhel;", "brenton": "And all the dwellers in Egypt shall know that I am the Lord, because thou hast been a staff of reed to the house of Israel."}}, {"v": 7, "ref": "29:7", "o": "בְּ/תָפְשָׂ֨/ם בְּ/ךָ֤ ב/כפ/ך בַ/כַּף֙ תֵּר֔וֹץ וּ/בָקַעְתָּ֥ לָ/הֶ֖ם כָּל כָּתֵ֑ף וּ/בְ/הִֽשָּׁעֲנָ֤/ם עָלֶ֨י/ךָ֙ תִּשָּׁבֵ֔ר וְ/הַעֲמַדְתָּ֥ לָ/הֶ֖ם כָּל מָתְנָֽיִם", "en": {"kjv": "When they took hold of thee by thy hand, thou didst break, and rend all their shoulder: and when they leaned upon thee, thou brakest, and madest all their loins to be at a stand.", "web": "When they took hold of you by your hand, you broke, and tore all their shoulders; and when they leaned on you, you broke, and paralyzed all of their thighs.”", "bsb": "When Israel took hold of you with their hands, you splintered, tearing all their shoulders; when they leaned on you, you broke, and their backs were wrenched.", "asv": "When they took hold of thee by thy hand, thou didst break, and didst rend all their shoulders; and when they leaned upon thee, thou brakest, and madest all their loins to be at a stand.", "ylt": "In their taking hold of thee by thy hand, --thou art crushed, And hast rent to them all the shoulder, And in their leaning on thee thou art broken, And hast caused all their thighs to stand.", "dra": "When they took hold of thee with the hand thou didst break, and rent all their shoulder: and when they leaned upon thee, thou brokest, and weakenest all their loins.", "bbe": "When they took a grip of you in their hands, you were crushed so that their arms were broken: and when they put their weight on you for support, you were broken and all their muscles gave way.", "geneva": "When they tooke holde of thee with their hand, thou diddest breake, and rent all their shoulder: and when they leaned vpon thee, thou brakest and madest all their loynes to stand vpright.", "wycliffe": "and thou were brokun, and to-rentist ech schuldre of hem, and whanne thei restiden on thee, thou were maad lesse, and thou hast discoumfortid alle the reynes of hem;", "rotherham": "Whensoever they took hold of thee by the hand, thou didst run through, and tear open for them every hand, —And whensoever they leaned upon thee, thou didst break, and caused all their loins to halt.", "darby": "When they took hold of thee by thy hand, thou didst give way and rend all their shoulder; and when they leaned upon thee, thou didst break, and didst make all their loins to tremble.", "twenty": "", "jps": "When they take hold of thee with the hand, thou dost break, and rend all their shoulders; and when they lean upon thee, thou breakest, and makest all their loins to be at a stand.", "acv": "When they took hold of thee by thy hand, thou broke, and tore all their shoulders. And when they leaned upon thee, thou broke, and made all their loins to be at a stand still.", "anderson": "", "haweis": "", "noyes": "When they took hold of thee by thy handle, thou didst break and pierce their whole shoulder; and when they leaned upon thee, thou didst go to pieces, and madest all their loins to shake.", "webster": "When they took hold of thee by thy hand, thou didst break, and rend all their shoulder: and when they leaned upon thee, thou didst break, and make all their loins to be at a stand.", "vulgate": "quando adprehenderunt te manu et confractus es et lacerasti omnem umerum eorum et innitentibus eis super te comminutus es et dissolvisti omnes renes eorum;", "brenton": "When they took hold of thee with their hand, thou didst break: and when every hand was clapped against them, and when they leaned on thee, thou wast utterly broken, and didst crush the loins of them all."}}, {"v": 8, "ref": "29:8", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֛י מֵבִ֥יא עָלַ֖יִ/ךְ חָ֑רֶב וְ/הִכְרַתִּ֥י מִמֵּ֖/ךְ אָדָ֥ם וּ/בְהֵמָֽה", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I will bring a sword upon thee, and cut off man and beast out of thee.", "web": "Therefore thus says the Lord Yahweh: “Behold, I will bring a sword on you, and will cut off man and animal from you.", "bsb": "Therefore this is what the Lord GOD says: I will bring a sword against you and cut off from you man and beast.", "asv": "Therefore thus saith the Lord Jehovah: Behold, I will bring a sword upon thee, and will cut off from thee man and beast.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am bringing in against thee a sword, And have cut off from thee man and beast.", "dra": "Therefore thus saith the Lord God: Behold, I will bring the sword upon thee: and cut off man and beast out of thee.", "bbe": "For this cause the Lord has said: See, I am sending a sword on you, cutting off from you man and beast.", "geneva": "Therefore thus sayeth the Lord God, Beholde, I will bring a sworde vpon thee, and destroy man and beast out of thee,", "wycliffe": "therfor the Lord God seith these thingis, Lo! Y schal bringe a swerd on thee, and Y schal sle of thee man and beeste;", "rotherham": "Therefore, Thus saith My Lord Yahweh, Behold me! bringing upon thee a sword,- And I will cut off out of thee, man and beast;", "darby": "Therefore thus saith the Lord Jehovah: Behold, I will bring a sword upon thee, and cut off man and beast from thee.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Behold, I will bring a sword upon thee, and will cut off from thee man and beast.", "acv": "Therefore thus says the lord Jehovah: Behold, I will bring a sword upon thee, and will cut off from thee man and beast.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, I will bring a sword upon thee, and cut off man and beast out of thee;", "webster": "Therefore thus saith the Lord GOD; Behold, I will bring a sword upon thee, and cut off man and beast out of thee.", "vulgate": "propterea haec dicit Dominus Deus ecce ego adducam super te gladium et interficiam de te hominem et iumentum;", "brenton": "Therefore thus saith the Lord; Behold, I will bring a sword upon thee, and will cut off from thee man and beast;"}}, {"v": 9, "ref": "29:9", "o": "וְ/הָיְתָ֤ה אֶֽרֶץ מִצְרַ֨יִם֙ לִ/שְׁמָמָ֣ה וְ/חָרְבָּ֔ה וְ/יָדְע֖וּ כִּֽי אֲנִ֣י יְהוָ֑ה יַ֧עַן אָמַ֛ר יְאֹ֥ר לִ֖/י וַ/אֲנִ֥י עָשִֽׂיתִי", "en": {"kjv": "And the land of Egypt shall be desolate and waste; and they shall know that I am the Lord: because he hath said, The river is mine, and I have made it.", "web": "The land of Egypt shall be a desolation and a waste; and they shall know that I am Yahweh. Because he has said, ‘The river is mine, and I have made it;’", "bsb": "The land of Egypt will become a desolate wasteland. Then they will know that I am the LORD. Because you said, ‘The Nile is mine; I made it,’", "asv": "And the land of Egypt shall be a desolation and a waste; and they shall know that I am Jehovah. Because he hath said, The river is mine, and I have made it;", "ylt": "And the land of Egypt hath been for a desolation and a waste, And they have known that I am Jehovah. Because he said: The flood is mine, and I made it .", "dra": "And the land of Egypt shall become a desert, and a wilderness: and they shall know that I am the Lord, because thou hast said: The river is mine, and I made it.", "bbe": "And the land of Egypt will be an unpeopled waste; and they will be certain that I am the Lord: because he has said, The Nile is mine, and I made it.", "geneva": "And the land of Egypt shalbe desolate, and waste, and they shall know that I am ye Lord: because he hath said, The riuer is mine, and I haue made it,", "wycliffe": "and the lond of Egipt schal be in to desert, and in to wildirnesse, and thei schulen wite, that Y am the Lord. For that that thou seidist, The flood is myn, and Y made it, therfor lo!", "rotherham": "And the land of Egypt shall become an astonishment and a desolation, So shall they know that, I, am Yahweh,—Because he said— The river is mine own, Since, I, myself made it!", "darby": "And the land of Egypt shall be a desolation and a waste: and they shall know that I [am] Jehovah, because he saith, The river is mine, and I made it.", "twenty": "", "jps": "And the land of Egypt shall be desolate and waste, and they shall know that I am HaShem; because he hath said: The river is mine, and I have made it.", "acv": "And the land of Egypt shall be a desolation and a waste. And they shall know that I am Jehovah. Because he has said, The river is mine, and I have made it,", "anderson": "", "haweis": "", "noyes": "and the land of Egypt shall be desolate and waste; and they shall know that I am Jehovah, because he hath said, \"The river is mine, and I have made it.\"", "webster": "And the land of Egypt shall be desolate and waste; and they shall know that I [am] the LORD: because he hath said, The river [is] mine, and I have made [it].", "vulgate": "et erit terra Aegypti in desertum et solitudinem et scient quia ego Dominus eo quod dixerit fluvius meus est et ego feci;", "brenton": "and the land of Egypt shall be ruined and desert; and they shall know that I am the Lord; because thou sayest, The rivers are mine, and I made them."}}, {"v": 10, "ref": "29:10", "o": "לָ/כֵ֛ן הִנְ/נִ֥י אֵלֶ֖י/ךָ וְ/אֶל יְאֹרֶ֑י/ךָ וְ/נָתַתִּ֞י אֶת אֶ֣רֶץ מִצְרַ֗יִם לְ/חָרְבוֹת֙ חֹ֣רֶב שְׁמָמָ֔ה מִ/מִּגְדֹּ֥ל סְוֵנֵ֖ה וְ/עַד גְּב֥וּל כּֽוּשׁ", "en": {"kjv": "Behold, therefore I am against thee, and against thy rivers, and I will make the land of Egypt utterly waste and desolate, from the tower of Syene even unto the border of Ethiopia.", "web": "therefore, behold, I am against you, and against your rivers, and I will make the land of Egypt an utter waste and desolation, from the tower of Seveneh even to the border of Ethiopia.", "bsb": "therefore I am against you and against your rivers. I will turn the land of Egypt into a ruin, a desolate wasteland from Migdol to Syene, and as far as the border of Cush.", "asv": "therefore, behold, I am against thee, and against thy rivers, and I will make the land of Egypt an utter waste and desolation, from the tower of Seveneh even unto the border of Ethiopia.", "ylt": "Therefore, lo, I am against thee, and against thy floods, And have given the land of Egypt for wastes, A waste, a desolation, from Migdol to Syene, And unto the border of Cush.", "dra": "Therefore, behold I come against thee, and thy rivers: and I will make the land of Egypt utterly desolate, and wasted by the sword, from the tower of Syene, even to the borders of Ethiopia.", "bbe": "See, then, I am against you and against your streams, and I will make the land of Egypt an unpeopled waste, from Migdol to Syene, even as far as the edge of Ethiopia.", "geneva": "Behold, therefore I come vpon thee, and vpon thy riuers, and I will make the land of Egypt vtterly waste and desolate from the towre of Seueneh, euen vnto the borders of the blacke Mores.", "wycliffe": "Y to thee, and to thi floodis. And Y schal yyue `in to wildirnesses the lond of Egipt distried bi swerd, fro the tour of Sienes til to the termes of Ethiopie.", "rotherham": "Therefore, behold me! against thee and against thy rivers,- And I will make the land of Egypt to be most desolate an astounding desolation, from Migdol to Syene even up to the boundary of Ethiopia:", "darby": "Therefore behold, I am against thee, and against thy rivers, and I will make the land of Egypt deserts of wasteness and desolation, from Migdol to Syene, even unto the border of Ethiopia.", "twenty": "", "jps": "Therefore, behold, I am against thee, and against thy rivers, and I will make the land of Egypt utterly waste and desolate, from Migdol to Syene even unto the border of Ethiopia.", "acv": "therefore, behold, I am against thee, and against thy rivers. And I will make the land of Egypt an utter waste and desolation, from the tower of Seveneh even to the border of Ethiopia.", "anderson": "", "haweis": "", "noyes": "Therefore, behold, I am against thee, and against thy rivers; and I will make the land of Egypt utterly waste and desolate, from Migdol even to Syene, and to the borders of Ethiopia.", "webster": "Behold, therefore, I [am] against thee, and against thy rivers, and I will make the land of Egypt utterly waste [and] desolate, from the tower of Syene even to the border of Cush.", "vulgate": "idcirco ecce ego ad te et ad flumina tua daboque terram Aegypti in solitudines gladio dissipatam a turre Syenes usque ad terminos Aethiopiae;", "brenton": "Therefore, behold, I am against thee, and against all thy rivers, and I will give up the land of Egypt to desolation, and the sword, and destruction, from Magdol and Syene even to the borders of the Ethiopians."}}, {"v": 11, "ref": "29:11", "o": "לֹ֤א תַעֲבָר בָּ/הּ֙ רֶ֣גֶל אָדָ֔ם וְ/רֶ֥גֶל בְּהֵמָ֖ה לֹ֣א תַעֲבָר בָּ֑/הּ וְ/לֹ֥א תֵשֵׁ֖ב אַרְבָּעִ֥ים שָׁנָֽה", "en": {"kjv": "No foot of man shall pass through it, nor foot of beast shall pass through it, neither shall it be inhabited forty years.", "web": "No foot of man shall pass through it, nor foot of animal shall pass through it, neither shall it be inhabited forty years.", "bsb": "No foot of man or beast will pass through, and it will be uninhabited for forty years.", "asv": "No foot of man shall pass through it, nor foot of beast shall pass through it, neither shall it be inhabited forty years.", "ylt": "Not pass over into it doth a foot of man, Yea, the foot of beast doth not pass into it, Nor is it inhabited forty years.", "dra": "The foot of man shall not pass through it, neither shall the foot of beasts go through it: nor shall it be inhabited during forty years.", "bbe": "No foot of man will go through it and no foot of beast, and it will be unpeopled for forty years.", "geneva": "No foote of man shall passe by it, nor foote of beast shall passe by it, neither shall it be inhabited fourtie yeeres.", "wycliffe": "The foot of man schal not passe bi it, nether the foot of beeste schal go in it, and it schal not be enhabitid in fourti yeer.", "rotherham": "The foot of man shall not pass through it, Nor shall the foot of beast, pass through it, Neither shall it be inhabited forty years:", "darby": "No foot of man shall pass through it, nor shall foot of beast pass through it, nor shall it be inhabited, forty years.", "twenty": "", "jps": "No foot of man shall pass through it, nor foot of beast shall pass through it, neither shall it be inhabited forty years.", "acv": "No foot of man shall pass through it, nor foot of beast shall pass through it. Neither shall it be inhabited forty years.", "anderson": "", "haweis": "", "noyes": "There shall not pass through it the foot of man, and the foot of beast shall not pass through it, neither shall it be inhabited forty years.", "webster": "No foot of man shall pass through it, nor foot of beast shall pass through it, neither shall it be inhabited forty years.", "vulgate": "non pertransibit eam pes hominis neque pes iumenti gradietur in ea et non habitabitur quadraginta annis;", "brenton": "No foot of man shall pass through it, and no foot of beast shall pass through it, and it shall not be inhabited for forty years."}}, {"v": 12, "ref": "29:12", "o": "וְ/נָתַתִּ֣י אֶת אֶרֶץ֩ מִצְרַ֨יִם שְׁמָמָ֜ה בְּ/ת֣וֹךְ אֲרָצ֣וֹת נְשַׁמּ֗וֹת וְ/עָרֶ֨י/הָ֙ בְּ/ת֨וֹךְ עָרִ֤ים מָֽחֳרָבוֹת֙ תִּֽהְיֶ֣יןָ שְׁמָמָ֔ה אַרְבָּעִ֖ים שָׁנָ֑ה וַ/הֲפִצֹתִ֤י אֶת מִצְרַ֨יִם֙ בַּ/גּוֹיִ֔ם וְֽ/זֵרִיתִ֖י/ם בָּ/אֲרָצֽוֹת", "en": {"kjv": "And I will make the land of Egypt desolate in the midst of the countries that are desolate, and her cities among the cities that are laid waste shall be desolate forty years: and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "web": "I will make the land of Egypt a desolation in the midst of the countries that are desolate; and her cities among the cities that are laid waste shall be a desolation forty years; and I will scatter the Egyptians among the nations, and will disperse them through the countries.”", "bsb": "I will make the land of Egypt a desolation among desolate lands, and her cities will lie desolate for forty years among the ruined cities. And I will disperse the Egyptians among the nations and scatter them throughout the countries.", "asv": "And I will make the land of Egypt a desolation in the midst of the countries that are desolate; and her cities among the cities that are laid waste shall be a desolation forty years; and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "ylt": "And I have made the land of Egypt a desolation, In the midst of desolate lands, And its cities, in the midst of waste cities, Are a desolation forty years, And I have scattered the Egyptians among nations, And I have dispersed them through lands.", "dra": "And I will make the land of Egypt desolate in the midst of the lands that are desolate, and the cities thereof in the midst of the cites that are destroyed, and they shall be desolate for forty years: and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "bbe": "I will make the land of Egypt a waste among the countries which are made waste, and her towns will be unpeopled among the towns which have been made waste, for forty years: and I will send the Egyptians in flight among the nations and wandering through the countries.", "geneva": "And I wil make the land of Egypt desolate in the middes of the countries, that are desolate, and her cities shall be desolate among the cities that are desolate, for fourtie yeeres: and I wil scatter the Egyptians among the nations, and wil disperse them through the countreis.", "wycliffe": "And Y schal yyue the lond of Egipt forsakun, in the myddis of londis forsakun, and the citees therof in the myddis of a citee distried, and tho schulen be desolat bi fourti yeer. And Y schal scatere Egipcians in to naciouns, and Y schal wyndewe hem in to londis.", "rotherham": "So will I make the land of Egypt a desolation in the midst of lands made desolate And her cities—in the midst of cities that have been laid waste, shall become a desolation forty years,- And I will disperse the Egyptians among the nations, And scatter them throughout the lands.", "darby": "And I will make the land of Egypt a desolation in the midst of the countries that are desolated, and her cities shall be, in the midst of the cities that are laid waste, a desolation forty years; and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "twenty": "", "jps": "And I will make the land of Egypt desolate in the midst of the countries that are desolate, and her cities among the cities that are laid waste shall be desolate forty years; and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "acv": "And I will make the land of Egypt a desolation in the midst of the countries that are desolate. And her cities among the cities that are laid waste shall be a desolation forty years. And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "anderson": "", "haweis": "", "noyes": "I will make the land of Egypt desolate amidst the lands that are desolate, and her cities, among the cities that are laid waste, shall be desolate forty years; and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "webster": "And I will make the land of Egypt desolate in the midst of the countries [that are] desolate, and her cities among the cities [that are] laid waste shall be desolate forty years: and I will scatter the Egyptians among the nations, and will disperse them through the countries.", "vulgate": "daboque terram Aegypti desertam in medio terrarum desertarum et civitates eius in medio urbium subversarum erunt desolatae quadraginta annis et dispergam Aegyptios in nationes et ventilabo eos in terras;", "brenton": "And I will cause her land to be utterly destroyed in the midst of a land that is desolate, and her cities shall be desolate forty years in the midst of cities that are desolate: and I will disperse Egypt among the nations, and will utterly scatter them into the countries."}}, {"v": 13, "ref": "29:13", "o": "כִּ֛י כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה מִ/קֵּ֞ץ אַרְבָּעִ֤ים שָׁנָה֙ אֲקַבֵּ֣ץ אֶת מִצְרַ֔יִם מִן הָ/עַמִּ֖ים אֲשֶׁר נָפֹ֥צוּ שָֽׁמָּ/ה", "en": {"kjv": "Yet thus saith the Lord God; At the end of forty years will I gather the Egyptians from the people whither they were scattered:", "web": "For thus says the Lord Yahweh: “At the end of forty years will I gather the Egyptians from the peoples where they were scattered;", "bsb": "For this is what the Lord GOD says: At the end of forty years I will gather the Egyptians from the nations to which they were scattered.", "asv": "For thus saith the Lord Jehovah: At the end of forty years will I gather the Egyptians from the peoples whither they were scattered;", "ylt": "But thus said the Lord Jehovah: At the end of forty years I gather the Egyptians Out of the peoples whither they have been scattered,", "dra": "For thus saith the Lord God: At the end of forty years I will gather the Egyptians from the people among whom they had been scattered.", "bbe": "For this is what the Lord has said: At the end of forty years I will get the Egyptians together from the peoples where they have gone in flight:", "geneva": "Yet thus saieth the Lord God, At the end of fourtie yeeres will I gather the Egyptians from the people, where they were scattered,", "wycliffe": "For the Lord God seith these thingis, After the ende of fourti yeer Y schal gadere togidere Egipt fro puplis, among whiche thei weren scaterid;", "rotherham": "For thus, saith My Lord Yahweh,— At the end of forty years, will I gather the Egyptians from among the peoples whither I had dispersed them;", "darby": "Yet thus saith the Lord Jehovah: At the end of forty years will I gather the Egyptians from the peoples whither they were scattered;", "twenty": "", "jps": "For thus saith the L-rd GOD: At the end of forty years will I gather the Egyptians from the peoples whither they were scattered;", "acv": "For thus says the lord Jehovah: At the end of forty years I will gather the Egyptians from the peoples where they were scattered,", "anderson": "", "haweis": "", "noyes": "Yet thus saith the Lord Jehovah: At the end of forty years will I gather the Egyptians from the nations whither they are scattered;", "webster": "Yet thus saith the Lord GOD; At the end of forty years will I gather the Egyptians from the people whither they were scattered:", "vulgate": "quia haec dicit Dominus Deus post finem quadraginta annorum congregabo Aegyptum de populis in quibus dispersi fuerunt;", "brenton": "Thus saith the Lord; After forty years I will gather the Egyptians from the nations among whom they have been scattered;"}}, {"v": 14, "ref": "29:14", "o": "וְ/שַׁבְתִּי֙ אֶת שְׁב֣וּת מִצְרַ֔יִם וַ/הֲשִׁבֹתִ֤י אֹתָ/ם֙ אֶ֣רֶץ פַּתְר֔וֹס עַל אֶ֖רֶץ מְכֽוּרָתָ֑/ם וְ/הָ֥יוּ שָׁ֖ם מַמְלָכָ֥ה שְׁפָלָֽה", "en": {"kjv": "And I will bring again the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their habitation; and they shall be there a base kingdom.", "web": "and I will bring back the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their birth; and they shall be there a base kingdom.", "bsb": "I will restore Egypt from captivity and bring them back to the land of Pathros, the land of their origin. There they will be a lowly kingdom.", "asv": "and I will bring back the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their birth; and they shall be there a base kingdom.", "ylt": "And I have turned back to the captivity of Egypt, And I have brought them back To the land of Pathros, to the land of their birth, And they have been there a low kingdom.", "dra": "And I will bring back the captivity of Egypt, and will place them in the land of Phatures, in the land of their nativity, and they shall be there a low kingdom:", "bbe": "I will let the fate of Egypt be changed, and will make them come back into the land of Pathros, into the land from which they came; and there they will be an unimportant kingdom.", "geneva": "And I wil bring againe the captiuitie of Egypt, and will cause them to returne into the land of Pathros, into the lande of their habitation, and they shalbe there a small kingdome.", "wycliffe": "and Y schal bringe ayen the caitifte of Egipte. And Y schal sette hem in the lond of Phatures, in the lond of her birthe; and thei schulen be there in to a meke rewme,", "rotherham": "And I will turn the captivity of the Egyptians, And will cause them to return To the land of Pathros Upon the land of their nativity,- And they shall become, there a kingdom abased:", "darby": "and I will turn again the captivity of Egypt, and will cause them to return to the land of Pathros, into the land of their birth, and they shall there be a base kingdom.", "twenty": "", "jps": "and I will turn the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their origin; and they shall be there a lowly kingdom.", "acv": "and I will bring back the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their birth. And they shall be a base kingdom there.", "anderson": "", "haweis": "", "noyes": "and I will bring back the captives of Egypt, and will cause them to return into the land of Pathros, into the land of their origin; and they shall be there a mean kingdom;", "webster": "And I will bring again the captivity of Egypt, and will cause them to return [into] the land of Pathros, into the land of their habitation; and they shall be there a base kingdom.", "vulgate": "et reducam captivitatem Aegypti et conlocabo eos in terra Fatures in terra nativitatis suae et erunt ibi in regnum humile;", "brenton": "and I will turn the captivity of the Egyptians, and will cause them to dwell in the land of Phathore, in the land whence they were taken;"}}, {"v": 15, "ref": "29:15", "o": "מִן הַ/מַּמְלָכוֹת֙ תִּהְיֶ֣ה שְׁפָלָ֔ה וְ/לֹֽא תִתְנַשֵּׂ֥א ע֖וֹד עַל הַ/גּוֹיִ֑ם וְ/הִ֨מְעַטְתִּ֔י/ם לְ/בִלְתִּ֖י רְד֥וֹת בַּ/גּוֹיִֽם", "en": {"kjv": "It shall be the basest of the kingdoms; neither shall it exalt itself any more above the nations: for I will diminish them, that they shall no more rule over the nations.", "web": "It shall be the base of the kingdoms; neither shall it any more lift itself up above the nations: and I will diminish them, that they shall no more rule over the nations.", "bsb": "Egypt will be the lowliest of kingdoms and will never again exalt itself above the nations. For I will diminish Egypt so that it will never again rule over the nations.", "asv": "It shall be the basest of the kingdoms; neither shall it any more lift itself up above the nations: and I will diminish them, that they shall no more rule over the nations.", "ylt": "Of the kingdoms it is lowest, And it lifteth not up itself any more above the nations, And I have made them few, So as not to rule among nations.", "dra": "It shall be the lowest among other kingdoms, and it shall no more be exalted over the nations, and I will diminish them that they shall rule no more over the nations.", "bbe": "It will be the lowest of the kingdoms, and never again will it be lifted up over the nations: I will make them small, so that they may not have rule over the nations.", "geneva": "It shall be the smallest of the kingdomes, neither shall it exalt it selfe any more aboue the nations: for I will diminish them, that they shall no more rule the nations.", "wycliffe": "and among othere rewmes it schal be most low, and it schal no more be reisid ouer naciouns. And Y schal make hem lesse, that thei regne not on hethene men;", "rotherham": "More than [any of] the kingdoms, shall she be abased, And shall lift herself up no more over the nations, —Yea I will make them too small to rule over the nations.", "darby": "It shall be the basest of kingdoms; neither shall it exalt itself any more above the nations; and I will diminish them, so that they shall no more rule over the nations.", "twenty": "", "jps": "It shall be the lowliest of the kingdoms, neither shall it any more lift itself up above the nations; and I will diminish them, that they shall no more rule over the nations.", "acv": "It shall be the basest of the kingdoms, nor shall it lift itself up any more above the nations. And I will diminish them, that they shall no more rule over the nations.", "anderson": "", "haweis": "", "noyes": "it shall be the meanest of all kingdoms; it shall no more exalt itself above the nations; for I will diminish them, that they shall no more rule over the nations.", "webster": "It shall be the basest of the kingdoms; neither shall it exalt itself any more above the nations: for I will diminish them, that they shall no more rule over the nations.", "vulgate": "inter regna cetera erit humillima et non elevabitur ultra super nationes et inminuam eos ne imperent gentibus;", "brenton": "and it shall be a base kingdom beyond all other kingdoms; it shall not any more be exalted over the nations; and I will make them few in number, that they may not be great among the nations."}}, {"v": 16, "ref": "29:16", "o": "וְ/לֹ֣א יִֽהְיֶה עוֹד֩ לְ/בֵ֨ית יִשְׂרָאֵ֤ל לְ/מִבְטָח֙ מַזְכִּ֣יר עָוֺ֔ן בִּ/פְנוֹתָ֖/ם אַחֲרֵי/הֶ֑ם וְ/יָ֣דְע֔וּ כִּ֥י אֲנִ֖י אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And it shall be no more the confidence of the house of Israel, which bringeth their iniquity to remembrance, when they shall look after them: but they shall know that I am the Lord God.", "web": "It shall be no more the confidence of the house of Israel, bringing iniquity to memory, when they turn to look after them: and they shall know that I am the Lord Yahweh.”’”", "bsb": "Egypt will never again be an object of trust for the house of Israel, but will remind them of their iniquity in turning to the Egyptians. Then they will know that I am the Lord GOD.”", "asv": "And it shall be no more the confidence of the house of Israel, bringing iniquity to remembrance, when they turn to look after them: and they shall know that I am the Lord Jehovah.", "ylt": "And it is no more to the house of Israel for a confidence, Bringing iniquity to remembrance, By their turning after them, And they have known that I am the Lord Jehovah.'", "dra": "And they shall be no more a confidence to the house of Israel, teaching iniquity, that they may flee, and follow them: and they shall know that I am the Lord God.", "bbe": "And Egypt will no longer be the hope of the children of Israel, causing sin to come to mind when their eyes are turned to them: and they will be certain that I am the Lord.", "geneva": "And it shall be no more the confidence of the house of Israel, to bring their iniquitie to remembrance by looking after them, so shall they knowe, that I am the Lord God.", "wycliffe": "and thei schulen no more be to the hous of Israel in trist, techinge wickidnesse, that thei fle, and sue hem; and thei schulen knowe, that Y am the Lord God.", "rotherham": "So shall it become no more unto the house of Israel a security. Calling to mind iniquity, by their turning to follow them,- And they shall know that, I, am The Lord Yahweh.", "darby": "And it shall be no more the confidence of the house of Israel, bringing iniquity to remembrance, when they turn after them: and they shall know that I [am] the Lord Jehovah.", "twenty": "", "jps": "And it shall be no more the confidence of the house of Israel, bringing iniquity to remembrance, when they turn after them; and they shall know that I am the L-rd GOD.'", "acv": "And it shall be no more the confidence of the house of Israel, bringing iniquity to remembrance, when they turn to look after them. And they shall know that I am the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And it shall be no more the confidence of the house of Israel, bringing to my remembrance their iniquity in looking to them for help; and they shall know that I am the Lord Jehovah.", "webster": "And it shall be no more the confidence of the house of Israel, which bringeth [their] iniquity to remembrance, when they shall look after them: but they shall know that I [am] the Lord GOD.", "vulgate": "neque erunt ultra domui Israhel in confidentia docentes iniquitatem ut fugiant et sequantur eos et scient quia ego Dominus Deus;", "brenton": "And they shall no more be to the house of Israel a confidence bringing iniquity to remembrance, when they follow after them; and they shall know that I am the Lord."}}, {"v": 17, "ref": "29:17", "o": "וַ/יְהִ֗י בְּ/עֶשְׂרִ֤ים וָ/שֶׁ֨בַע֙ שָׁנָ֔ה בָּֽ/רִאשׁ֖וֹן בְּ/אֶחָ֣ד לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass in the seven and twentieth year, in the first month, in the first day of the month, the word of the Lord came unto me, saying,", "web": "It came to pass in the seven and twentieth year, in the first month, in the first day of the month, Yahweh’s word came to me, saying,", "bsb": "In the twenty-seventh year, on the first day of the first month, the word of the LORD came to me, saying,", "asv": "And it came to pass in the seven and twentieth year, in the firstmonth, in the firstdayof the month, the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the twenty and seventh year, in the first month , in the first of the month, hath a word of Jehovah been unto me, saying:", "dra": "And it came to pass in the seven and twentieth year in the first month, in the first of the month: that the word of the Lord came to me, saying:", "bbe": "Now in the twenty-seventh year, in the first month, on the first day of the month, the word of the Lord came to me, saying,", "geneva": "In the seuen and twentieth yeere also in the first moneth, and in the first day of the moneth, came the word of the Lord vnto me, saying,", "wycliffe": "And it was don in the seuene and twentithe yeer, in the firste monethe, in the firste dai of the monethe, the word of the Lord was maad to me,", "rotherham": "And it came to pass in the twenty-seventh year in the first month on the first of the month, that the word of Yahweh came unto me saying:", "darby": "And it came to pass in the twenty-seventh year, in the first [month], on the first of the month, [that] the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass in the seven and twentieth year, in the first month, in the first day of the month, the word of HaShem came unto me, saying:", "acv": "And it came to pass in the twenty-seventh year, in the first month, in the first day of the month, the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And it came to pass in the twenty-seventh year, in the first month, on the first day of the month, that the word of Jehovah came to me, saying:", "webster": "And it came to pass in the seven and twentieth year, in the first [month], in the first [day] of the month, the word of the LORD came to me, saying,", "vulgate": "et factum est in vicesimo et septimo anno in primo in una mensis factum est verbum Domini ad me dicens;", "brenton": "And it came to pass in the twenty-seventh year, on the first day of the month, the word of the Lord came to me, saying,"}}, {"v": 18, "ref": "29:18", "o": "בֶּן אָדָ֗ם נְבוּכַדְרֶאצַּ֣ר מֶֽלֶךְ בָּ֠בֶל הֶעֱבִ֨יד אֶת חֵיל֜/וֹ עֲבֹדָ֤ה גְדֹלָה֙ אֶל צֹ֔ר כָּל רֹ֣אשׁ מֻקְרָ֔ח וְ/כָל כָּתֵ֖ף מְרוּטָ֑ה וְ֠/שָׂכָר לֹא הָ֨יָה ל֤/וֹ וּ/לְ/חֵיל/וֹ֙ מִ/צֹּ֔ר עַל הָ/עֲבֹדָ֖ה אֲשֶׁר עָבַ֥ד עָלֶֽי/הָ", "en": {"kjv": "Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyrus: every head was made bald, and every shoulder was peeled: yet had he no wages, nor his army, for Tyrus, for the service that he had served against it:", "web": "Son of man, Nebuchadnezzar king of Babylon caused his army to serve a great service against Tyre: every head was made bald, and every shoulder was worn; yet had he no wages, nor his army, from Tyre, for the service that he had served against it.", "bsb": "“Son of man, Nebuchadnezzar king of Babylon caused his army to labor strenuously against Tyre. Every head was made bald and every shoulder made raw. But he and his army received no wages from Tyre for the labor they expended on it.", "asv": "Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyre: every head was made bald, and every shoulder was worn; yet had he no wages, nor his army, from Tyre, for the service that he had served against it.", "ylt": "`Son of man, Nebuchadrezzar king of Babylon, Hath caused his force to serve a great service against Tyre, Every head is bald--every shoulder peeled, And reward he had none, nor his force, out of Tyre, For the service that he served against it.", "dra": "Son of man, Nabuchodonosor king of Babylon hath made his army to undergo hard service against Tyre: every head was made bald, and every shoulder was peeled and there hath been no reward given him, nor his army for Tyre, for the service that he rendered me against it.", "bbe": "Son of man, Nebuchadrezzar, king of Babylon, made his army do hard work against Tyre, and the hair came off every head and every arm was rubbed smooth: but he and his army got no payment out of Tyre for the hard work which he had done against it.", "geneva": "Sonne of man, Nebuchad-nezzar King of Babel caused his armie to serue a great seruice against Tyrus: euery head was made balde, and euery shoulder was made bare: yet had he no wages, nor his armie for Tyrus, for the seruice that he serued against it.", "wycliffe": "and he seide, Thou, sone of man, Nabugodonosor, kyng of Babiloyne, made his oost to serue bi greet seruyce ayens Tire; ech heed was maad ballid, and ech schuldir was maad bare of heer, and meede was not yoldun of Tire to hym, nether to his oost, for the seruyce bi which he seruede to me ayens it.", "rotherham": "Son of man Nebuchadrezzar king of Babylon, hath made his army undergo a long service against Tyre, Every head, hath been made bald, and, Every shoulder, worn bare,— But pay, hath he had none nor hath his army, out of Tyre, for the service wherewith he hath served against it.", "darby": "Son of man, Nebuchadrezzar king of Babylon caused his army to do hard service against Tyre; every head was made bald, and every shoulder was peeled: yet had he from Tyre no wages, nor his army, for the service that he had served against it.", "twenty": "", "jps": "'Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyre; every head was made bald, and every shoulder was peeled; yet had he no wages, nor his army, from Tyre, for the service that he had served against it;", "acv": "Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyre. Every head was made bald, and every shoulder was worn, yet he had no wages, nor his army, from Tyre, for the service that he had served against it.", "anderson": "", "haweis": "", "noyes": "Son of man, Nebuchadnezzar, the king of Babylon, caused his army to serve a great service against Tyre; every head was made bald, and every shoulder was peeled; yet neither he nor his army had wages from Tyre for the service which he served against it.", "webster": "Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyre: every head [was] made bald, and every shoulder [was] peeled: yet had he no wages, nor his army, for Tyre, for the service that he had served against it:", "vulgate": "fili hominis Nabuchodonosor rex Babylonis servire fecit exercitum suum servitute magna adversum Tyrum omne caput decalvatum et omnis umerus depilatus est et merces non est reddita ei neque exercitui eius de Tyro pro servitute qua servivit mihi adversum eam;", "brenton": "Son of man, Nabuchodonosor king of Babylon caused his army to serve a great service against Tyre; every head was bald, and every shoulder peeled; yet there was no reward to him or to his army serving against Tyre, nor for the service wherewith they served against it."}}, {"v": 19, "ref": "29:19", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֥י נֹתֵ֛ן לִ/נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ בָּבֶ֖ל אֶת אֶ֣רֶץ מִצְרָ֑יִם וְ/נָשָׂ֨א הֲמֹנָ֜/הּ וְ/שָׁלַ֤ל שְׁלָלָ/הּ֙ וּ/בָזַ֣ז בִּזָּ֔/הּ וְ/הָיְתָ֥ה שָׂכָ֖ר לְ/חֵילֽ/וֹ", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall take her multitude, and take her spoil, and take her prey; and it shall be the wages for his army.", "web": "Therefore thus says the Lord Yahweh: Behold, I will give the land of Egypt to Nebuchadnezzar king of Babylon; and he shall carry off her multitude, and take her plunder, and take her prey; and it shall be the wages for his army.", "bsb": "Therefore this is what the Lord GOD says: I will give the land of Egypt to Nebuchadnezzar king of Babylon, who will carry off its wealth, seize its spoil, and remove its plunder. This will be the wages for his army.", "asv": "Therefore thus saith the Lord Jehovah: Behold, I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall carry off her multitude, and take her spoil, and take her prey; and it shall be the wages for his army.", "ylt": "Therefore, thus said the Lord Jehovah, Lo, I am giving to Nebuchadrezzar king of Babylon the land of Egypt, And he hath taken away its store, And hath taken its spoil, and taken its prey, And it hath been a reward to his force.", "dra": "Therefore thus saith the Lord God: Behold, I will set Nabuchodonosor the king of Babylon in the land of Egypt: and he shall take her multitude, and take the booty thereof for a prey, and rifle the spoils thereof: and it shall be wages for his army.", "bbe": "For this cause the Lord has said: See, I am giving the land of Egypt to Nebuchadrezzar, king of Babylon: he will take away her wealth, and take her goods by force and everything which is there; and this will be the payment for his army.", "geneva": "Therefore thus sayth the Lord God, Beholde, I will giue the land of Egypt vnto Nebuchad-nezzar the King of Babel, and he shall take her multitude, and spoyle her spoyle, and take her pray, and it shall be the wages for his armie.", "wycliffe": "Therfor the Lord God seith these thingis, Lo! Y schal yyue Nabugodonosor, kyng of Babiloyne, in the lond of Egipt, and he schal take the multitude therof; and he schal take in preye the clothis therof, and he schal rauysche the spuylis therof, and meede schal be to his oost,", "rotherham": "Therefore, Thus, saith My Lord Yahweh, Behold me! giving to Nebuchadrezzar king of Babylon, the land of Egypt,— And he shall carry off her multitude And capture her spoil And seize her prey, So shall she become pay for his army.", "darby": "Therefore thus saith the Lord Jehovah: Behold, I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall carry away her multitude, and seize her spoil, and take her prey; and it shall be the wages for his army.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Behold, I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall carry off her abundance, and take her spoil, and take her prey; and it shall be the wages for his army.", "acv": "Therefore thus says the lord Jehovah: Behold, I will give the land of Egypt to Nebuchadrezzar king of Babylon, and he shall carry off her multitude, and take her spoil, and take her prey. And it shall be the wages for his army.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, I will give the land of Egypt to Nebuchadnezzar, the king of Babylon, and he shall take her multitude, and take her spoil, and take her plunder; and it shall be wages for his army.", "webster": "Therefore thus saith the Lord GOD; Behold, I will give the land of Egypt to Nebuchadrezzar king of Babylon; and he shall take her multitude, and take her spoil, and take her prey; and it shall be the wages for his army.", "vulgate": "propterea haec dicit Dominus Deus ecce ego dabo Nabuchodonosor regem Babylonis in terra Aegypti et accipiet multitudinem eius et depraedabitur manubias eius et diripiet spolia eius et erit merces exercitui illius;", "brenton": "Thus saith the Lord God; Behold, I will give to Nabuchodonosor king of Babylon the land of Egypt, and he shall take the plunder thereof, and seize the spoils thereof; and it shall be a reward for his army."}}, {"v": 20, "ref": "29:20", "o": "פְּעֻלָּת/וֹ֙ אֲשֶׁר עָ֣בַד בָּ֔/הּ נָתַ֥תִּי ל֖/וֹ אֶת אֶ֣רֶץ מִצְרָ֑יִם אֲשֶׁר֙ עָ֣שׂוּ לִ֔/י נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "I have given him the land of Egypt for his labour wherewith he served against it, because they wrought for me, saith the Lord God.", "web": "I have given him the land of Egypt as his recompense for which he served, because they worked for me, says the Lord Yahweh.", "bsb": "I have given him the land of Egypt as the reward for his labor, because it was done for Me, declares the Lord GOD.", "asv": "I have given him the land of Egypt as his recompense for which he served, because they wrought for me, saith the Lord Jehovah.", "ylt": "His wage for which he laboured I have given to him, The land of Egypt--in that they wrought for Me, An affirmation of the Lord Jehovah.", "dra": "And for the service that he hath done me against it: I have given him the land of Egypt, because he hath laboured for me, saith the Lord God.", "bbe": "I have given him the land of Egypt as the reward for his hard work, because they were working for me, says the Lord.", "geneva": "I haue giuen him the land of Egypt for his labour, that he serued against it, because they wrought for me, sayth the Lord God.", "wycliffe": "and to the werk for which he seruyde to me ayens it; and Y yaf the lond of Egipt to hym, for that that he trauelide to me, seith the Lord God.", "rotherham": "As a reward for his labour wherewith he hath served, have I given to him the land of Egypt,—in that they wrought for me, Declareth My Lord, Yahweh.", "darby": "I have given him the land of Egypt for his labour wherewith he served against it, because they wrought for me, saith the Lord Jehovah.", "twenty": "", "jps": "I have given him the land of Egypt as his hire for which he served, because they wrought for Me, saith the L-rd GOD.", "acv": "I have given him the land of Egypt as his recompense for which he served, because they worked for me, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "For his wages for his service I will give him the land of Egypt; for they wrought for me, saith the Lord Jehovah.", "webster": "I have given him the land of Egypt [for] his labor with which he served against it, because they wrought for me, saith the Lord GOD.", "vulgate": "et operi pro quo servivit adversum eam dedi ei terram Aegypti pro eo quod laboraverunt mihi ait Dominus Deus;", "brenton": "In return for his service wherewith he served against Tyre, I have given him the land of Egypt; thus saith the Lord God:"}}, {"v": 21, "ref": "29:21", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא אַצְמִ֤יחַ קֶ֨רֶן֙ לְ/בֵ֣ית יִשְׂרָאֵ֔ל וּ/לְ/ךָ֛ אֶתֵּ֥ן פִּתְחֽוֹן פֶּ֖ה בְּ/תוֹכָ֑/ם וְ/יָדְע֖וּ כִּי אֲנִ֥י יְהוָֽה", "en": {"kjv": "In that day will I cause the horn of the house of Israel to bud forth, and I will give thee the opening of the mouth in the midst of them; and they shall know that I am the Lord.", "web": "In that day will I cause a horn to sprout for the house of Israel, and I will give you the opening of the mouth in their midst; and they shall know that I am Yahweh.", "bsb": "In that day I will cause a horn to sprout for the house of Israel, and I will open your mouth to speak among them. Then they will know that I am the LORD.”", "asv": "In that day will I cause a horn to bud forth unto the house of Israel, and I will give thee the opening of the mouth in the midst of them; and they shall know that I am Jehovah.", "ylt": "In that day I cause to shoot up a horn to the house of Israel, And to thee I give an opening of the mouth in their midst, And they have known that I am Jehovah!'", "dra": "In that day a horn shall bud forth to the house of Israel, and I will give thee an open mouth in the midst of them: and they shall know that I am the Lord.", "bbe": "In that day I will make a horn put out buds for the children of Israel, and I will let your words come freely among them, and they will be certain that I am the Lord.", "geneva": "In that day will I cause the horne of the house of Israel to growe, and I will giue thee an open mouth in the middes of them, and they shall knowe that I am the Lord.", "wycliffe": "In that dai an horn of the hous of Israel schal come forth, and Y schal yyue to thee an open mouth in the myddis of hem; and thei schulen wite, that Y am the Lord.", "rotherham": "In that day, will I cause to bud a horn for the house of Israel, And to thee, will I give an opening of mouth in their midst, So shall they know that, I, am Yahweh.", "darby": "In that day will I cause the horn of the house of Israel to bud forth, and I will give thee the opening of the mouth in the midst of them: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "In that day will I cause a horn to shoot up unto the house of Israel, and I will give thee the opening of the mouth in the midst of them; and they shall know that I am HaShem.'", "acv": "In that day I will cause a horn to bud forth to the house of Israel, and I will give thee the opening of the mouth in the midst of them. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "In that day will I cause a horn to grow forth to the house of Israel, and I will give thee to open the mouth in the midst of them; and they shall know that I am Jehovah.", "webster": "In that day will I cause the horn of the house of Israel to bud forth, and I will give thee the opening of the mouth in the midst of them; and they shall know that I [am] the LORD.", "vulgate": "in die illo pullulabit cornu domui Israhel et tibi dabo apertum os in medio eorum et scient quoniam ego Dominus;", "brenton": "In that day shall a horn spring forth for all the house of Israel, and I will give thee an open mouth in the midst of them; and they shall know that I am the Lord."}}]}, {"c": 30, "verses": [{"v": 1, "ref": "30:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came again to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "The word of Jehovah came again unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "The word of the Lord came to me again, saying,", "geneva": "The worde of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came again to me, saying,", "anderson": "", "haweis": "", "noyes": "The word of Jehovah came again to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "30:2", "o": "בֶּן אָדָ֕ם הִנָּבֵא֙ וְ/אָ֣מַרְתָּ֔ כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הֵילִ֖ילוּ הָ֥הּ לַ/יּֽוֹם", "en": {"kjv": "Son of man, prophesy and say, Thus saith the Lord God; Howl ye, Woe worth the day!", "web": "Son of man, prophesy, and say, Thus says the Lord Yahweh: Wail, Alas for the day!", "bsb": "“Son of man, prophesy and declare that this is what the Lord GOD says: Wail, ‘Alas for that day!’", "asv": "Son of man, prophesy, and say, Thus saith the Lord Jehovah: Wail ye, Alas for the day!", "ylt": "`Son of man, prophesy, and thou hast said: Thus said the Lord Jehovah: Howl ye, ha! for the day!", "dra": "Son of man prophesy, and say: Thus saith the Lord God: Howl ye, Woe, woe to the day:", "bbe": "Son of man, be a prophet, and say, These are the words of the Lord: Give a cry, Aha, for the day!", "geneva": "Sonne of man, prophesie, and say, Thus sayth the Lord God, Howle and cry, Wo be vnto this day.", "wycliffe": "and he seide, Sone of man, profesie thou, and seie, The Lord God seith these thingis, Yelle ye, Wo!", "rotherham": "Son of man Prophesy. and thou shalt say, Thus saith My Lord Yahweh,— Howl ye. Alas for the day!", "darby": "Son of man, prophesy and say, Thus saith the Lord Jehovah: Howl ye, Alas for the day!", "twenty": "", "jps": "'Son of man, prophesy, and say: Thus saith the L-rd GOD: wail ye: Woe worth the day!", "acv": "Son of man, prophesy, and say, Thus says the lord Jehovah: Wail ye, Alas for the day!", "anderson": "", "haweis": "", "noyes": "Son of man, prophesy, and say, Thus saith the Lord Jehovah: Howl ye, Alas! alas for the day!", "webster": "Son of man, prophesy and say, Thus saith the Lord GOD; Howl ye, Alas the day!", "vulgate": "fili hominis propheta et dic haec dicit Dominus Deus ululate vae vae diei;", "brenton": "Son of man, prophesy, and say, Thus saith the Lord; Woe, woe worth the day!"}}, {"v": 3, "ref": "30:3", "o": "כִּֽי קָר֣וֹב י֔וֹם וְ/קָר֥וֹב י֖וֹם לַֽ/יהוָ֑ה י֣וֹם עָנָ֔ן עֵ֥ת גּוֹיִ֖ם יִֽהְיֶֽה", "en": {"kjv": "For the day is near, even the day of the Lord is near, a cloudy day; it shall be the time of the heathen.", "web": "For the day is near, even the day of Yahweh is near; it shall be a day of clouds, a time of the nations.", "bsb": "For the day is near, the Day of the LORD is near. It will be a day of clouds, a time of doom for the nations.", "asv": "For the day is near, even the day of Jehovah is near; it shall be a day of clouds, a time of the nations.", "ylt": "For near is a day, near is a day to Jehovah! A day of clouds, the time of nations it is.", "dra": "For the day is near, yea the day of the Lord is near: a cloudy day, it shall be the time of the nations.", "bbe": "For the day is near, the day of the Lord is near, a day of cloud; it will be the time of the nations.", "geneva": "For the day is neere, and the day of the Lord is at hand, a cloudie day, and it shall be the time of the heathen.", "wycliffe": "wo! to the dai, for the dai is niy; and the dai of the Lord neiyith, the dai of a cloude. The tyme of hethene men schal be;", "rotherham": "For near, is a day, Yea near, is a day pertaining to Yahweh, A day of cloud, A time of nations, shall it be!", "darby": "For the day is at hand, yea, the day of Jehovah is at hand, a day of clouds; it shall be the time of the nations.", "twenty": "", "jps": "For the day is near, even the day of HaShem is near, a day of clouds, it shall be the time of the nations.", "acv": "For the day is near, even the day of Jehovah is near. It shall be a day of clouds, a time of the nations.", "anderson": "", "haweis": "", "noyes": "For the day is near, the day of Jehovah is near! A day of clouds, the time of the nations is come.", "webster": "For the day [is] near, even the day of the LORD [is] near, a cloudy day; it shall be the time of the heathen.", "vulgate": "quia iuxta est dies et adpropinquavit dies Domini dies nubis tempus gentium erit;", "brenton": "For the day of the Lord is nigh, a day of cloud; it shall be the end of the nations."}}, {"v": 4, "ref": "30:4", "o": "וּ/בָאָ֥ה חֶ֨רֶב֙ בְּ/מִצְרַ֔יִם וְ/הָיְתָ֤ה חַלְחָלָה֙ בְּ/כ֔וּשׁ בִּ/נְפֹ֥ל חָלָ֖ל בְּ/מִצְרָ֑יִם וְ/לָקְח֣וּ הֲמוֹנָ֔/הּ וְ/נֶהֶרְס֖וּ יְסוֹדֹתֶֽי/הָ", "en": {"kjv": "And the sword shall come upon Egypt, and great pain shall be in Ethiopia, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be broken down.", "web": "A sword shall come on Egypt, and anguish shall be in Ethiopia, when the slain shall fall in Egypt; and they shall take away her multitude, and her foundations shall be broken down.", "bsb": "A sword will come against Egypt, and there will be anguish in Cush when the slain fall in Egypt, its wealth is taken away, and its foundations are torn down.", "asv": "And a sword shall come upon Egypt, and anguish shall be in Ethiopia, when the slain shall fall in Egypt; and they shall take away her multitude, and her foundations shall be broken down.", "ylt": "And come in hath a sword to Egypt, And there hath been great pain in Cush, In the falling of the wounded in Egypt, And they have taken its store, And broken down have been its foundations.", "dra": "And the sword shall come upon Egypt: and there shall be dread in Ethiopia, when the wounded shall fall in Egypt, and the multitude thereof shall be taken away, and the foundations thereof shall be destroyed.", "bbe": "And a sword will come on Egypt, and cruel pain will be in Ethiopia, when they are falling by the sword in Egypt; and they will take away her wealth and her bases will be broken down.", "geneva": "And the sword shall come vpon Egypt, and feare shall be in Ethiopia, when the slaine shall fall in Egypt, when they shall take away her multitude, and when her foundations shall be broken downe.", "wycliffe": "and a swerd schal come in to Egipt, and drede schal be in Ethiopie, whanne woundid men schulen falle doun in Egipt, and the multitude therof schal be takun awei, and the foundementis therof schulen be distried.", "rotherham": "Then shall come a sword into Egypt, And there shall be a pang in Ethiopia When the deadly wounded one falleth in Egypt,- And they take away her multitude, and, her foundations, are broken down.", "darby": "And the sword shall come upon Egypt, and there shall be anguish in Ethiopia, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be overthrown.", "twenty": "", "jps": "And a sword shall come upon Egypt, and convulsion shall be in Ethiopia, when the slain shall fall in Egypt; and they shall take away her abundance, and her foundation shall be broken down.", "acv": "And a sword shall come upon Egypt, and anguish shall be in Ethiopia, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be broken down.", "anderson": "", "haweis": "", "noyes": "The sword shall come upon Egypt, and anguish shall be in Ethiopia, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be destroyed.", "webster": "And the sword shall come upon Egypt, and great pain shall be in Cush, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be broken down.", "vulgate": "et veniet gladius in Aegyptum et erit pavor in Aethiopia cum ceciderint vulnerati in Aegypto et ablata fuerit multitudo illius et destructa fundamenta eius;", "brenton": "And the sword shall come upon the Egyptians, and there shall be tumult in Ethiopia, and in Egypt men shall fall down slain together, and her foundations shall fall."}}, {"v": 5, "ref": "30:5", "o": "כּ֣וּשׁ וּ/פ֤וּט וְ/לוּד֙ וְ/כָל הָ/עֶ֣רֶב וְ/כ֔וּב וּ/בְנֵ֖י אֶ֣רֶץ הַ/בְּרִ֑ית אִתָּ֖/ם בַּ/חֶ֥רֶב יִפֹּֽלוּ", "en": {"kjv": "Ethiopia, and Libya, and Lydia, and all the mingled people, and Chub, and the men of the land that is in league, shall fall with them by the sword.", "web": "Ethiopia, and Put, and Lud, and all the mixed people, and Cub, and the children of the land that is allied with them, shall fall with them by the sword.", "bsb": "Cush, Put, and Lud, and all the various peoples, as well as Libya and the men of the covenant land, will fall with Egypt by the sword.", "asv": "Ethiopia, and Put, and Lud, and all the mingled people, and Cub, and the children of the land that is in league, shall fall with them by the sword.", "ylt": "Cush, and Phut, and Lud, and all the mixture, and Chub, And the sons of the land of the covenant with them by sword do fall,", "dra": "Ethiopia, and Libya, and Lydia, and all the rest of the crowd, and Chub, and the children of the land of the covenant, shall fall with them by the sword.", "bbe": "Ethiopia and Put and Lud and all the mixed people and Libya and the children of the land of the Cherethites will all be put to death with them by the sword.", "geneva": "Ethiopia and Phut, and Lud, and all the common people, and Cub, and the men of the land, that is in league, shall fall with them by the sword.", "wycliffe": "Ethiopie, and Libie, and Lidiens, and al the residue comyn puple, and Chub, and the sones of the lond of boond of pees schulen falle doun bi swerd with hem.", "rotherham": "Ethiopia and Libya and Lydia, and all the mixed multitude and Cub, and the sons of the land of the covenant with them—by the sword, shall they fall.", "darby": "Cush, and Phut, and Lud, and all the mingled people, and Chub, and the children of the land that is in league, shall fall with them by the sword.", "twenty": "", "jps": "Ethiopia, and Put, and Lud, and all the mingled people, and Cub, and the children of the land that is in league, shall fall with them by the sword.", "acv": "Ethiopia, and Put, and Lud, and all the mixed people, and Cub, and the sons of the land that is in league, shall fall with them by the sword.", "anderson": "", "haweis": "", "noyes": "Ethiopia, and Lybia, and Lydia, and all her auxiliaries, and Chub, and the men of every country that is in league, shall fall with them by the sword.", "webster": "Cush, and Libya, and Lydia, and all the mingled people, and Kub, and the men of the land that is in league, shall fall with them by the sword.", "vulgate": "Aethiopia et Lybia et Lydii et omne reliquum vulgus et Chub et filii terrae foederis cum eis gladio cadent;", "brenton": "Persians, and Cretans, and Lydians, and Libyans, and all the mixed multitude, and they of the children of my covenant, shall fall by the sword therein."}}, {"v": 6, "ref": "30:6", "o": "כֹּ֚ה אָמַ֣ר יְהוָ֔ה וְ/נָֽפְלוּ֙ סֹמְכֵ֣י מִצְרַ֔יִם וְ/יָרַ֖ד גְּא֣וֹן עֻזָּ֑/הּ מִ/מִּגְדֹּ֣ל סְוֵנֵ֗ה בַּ/חֶ֨רֶב֙ יִפְּלוּ בָ֔/הּ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thus saith the Lord; They also that uphold Egypt shall fall; and the pride of her power shall come down: from the tower of Syene shall they fall in it by the sword, saith the Lord God.", "web": "Thus says Yahweh: They also who uphold Egypt shall fall; and the pride of her power shall come down: from the tower of Seveneh shall they fall in it by the sword, says the Lord Yahweh.", "bsb": "For this is what the LORD says: The allies of Egypt will fall, and her proud strength will collapse. From Migdol to Syene they will fall by the sword within her, declares the Lord GOD.", "asv": "Thus saith Jehovah: They also that uphold Egypt shall fall; and the pride of her power shall come down: from the tower of Seveneh shall they fall in it by the sword, saith the Lord Jehovah.", "ylt": "Thus said Jehovah: And--fallen have supporters of Egypt, And come down hath the arrogance of her strength, From Migdol to Syene, by sword they fall in her, An affirmation of the Lord Jehovah.", "dra": "Thus saith the Lord God: They also that uphold Egypt shall fall, and the pride of her empire shall be brought down: from the tower of Syene shall they fall in it by the sword, saith the Lord the God of hosts.", "bbe": "This is what the Lord has said: The supporters of Egypt will have a fall, and the pride of her power will come down: from Migdol to Syene they will be put to the sword in it, says the Lord.", "geneva": "Thus sayth the Lord, They also that mainteine Egypt, shall fall, and the pride of her power shall come downe: from the towre of Seueneh shall they fall by the sword, sayth the Lord God.", "wycliffe": "The Lord God seith these thingis, And thei that vndursetten Egipt schulen falle doun, and the pride of the lordschipe therof schal be destried; fro the tour of Sienes thei schulen falle bi swerd ther ynne, seith the Lord of oostis.", "rotherham": "Thus saith Yahweh, Then shall fall the supporters of Egypt, Then shall come down the pride of her strength, —From Migdol to Seweneh, by the sword shall they fall therein, Declareth My Lord, Yahweh.", "darby": "Thus saith Jehovah: They also that uphold Egypt shall fall; and the pride of her strength shall come down: from Migdol to Syene shall they fall in her by the sword, saith the Lord Jehovah.", "twenty": "", "jps": "Thus saith HaShem: they also that uphold Egypt shall fall, and the pride of her power shall come down; from Migdol to Syene shall they fall in it by the sword, saith the L-rd GOD.", "acv": "Thus says Jehovah: They also who uphold Egypt shall fall, and the pride of her power shall come down. From the tower of Seveneh they shall fall in it by the sword, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: They that uphold Egypt shall fall, and the pride of her power shall come down; from Migdol to Syene shall they fall in her by the sword, saith the Lord Jehovah.", "webster": "Thus saith the LORD; They also that uphold Egypt shall fall; and the pride of her power shall come down: from the tower of Syene shall they fall in it by the sword, saith the Lord GOD.", "vulgate": "haec dicit Dominus Deus et corruent fulcientes Aegyptum et destruetur superbia imperii eius a turre Syenes gladio cadent in ea ait Dominus exercituum;", "brenton": "And the supports of Egypt shall fall; and the pride of her strength shall come down from Magdol to Syene: they shall fall by the sword in it, saith the Lord."}}, {"v": 7, "ref": "30:7", "o": "וְ/נָשַׁ֕מּוּ בְּ/ת֖וֹךְ אֲרָצ֣וֹת נְשַׁמּ֑וֹת וְ/עָרָ֕י/ו בְּ/תוֹךְ עָרִ֥ים נַחֲרָב֖וֹת תִּֽהְיֶֽינָה", "en": {"kjv": "And they shall be desolate in the midst of the countries that are desolate, and her cities shall be in the midst of the cities that are wasted.", "web": "They shall be desolate in the midst of the countries that are desolate; and her cities shall be in the midst of the cities that are wasted.", "bsb": "They will be desolate among desolate lands, and their cities will lie among ruined cities.", "asv": "And they shall be desolate in the midst of the countries that are desolate; and her cities shall be in the midst of the cities that are wasted.", "ylt": "And they have been desolated in the midst of desolate lands, And its cities are in the midst of wasted cities.", "dra": "And they shall be desolate in the midst of the lands that are desolate, and the cities thereof shall be in the midst of the cities that are wasted.", "bbe": "And she will be made waste among the countries which have been made waste, and her towns will be among the towns which are unpeopled.", "geneva": "And they shall be desolate in the middes of the countries that are desolate, and her cities shall be in the middes of the cities that are wasted.", "wycliffe": "And thei schulen be distried in the myddis of londis maad desolat, and the citees therof schulen be in the myddis of citees forsakun.", "rotherham": "So shall they be made desolate in the midst of lands that are desolate,- And :his cities—in the midst of cities that are laid waste, shall be found.", "darby": "And they shall be desolated in the midst of the countries that are desolated, and her cities shall be in the midst of the cities that are wasted.", "twenty": "", "jps": "And they shall be desolate in the midst of the countries that are desolate, and her cities shall be in the midst of the cities that are wasted.", "acv": "And they shall be desolate in the midst of the countries that are desolate, and her cities shall be in the midst of the cities that are wasted.", "anderson": "", "haweis": "", "noyes": "And they shall be laid waste in the midst of the lands that are laid waste, and her cities shall be amongst the cities that are desolate.", "webster": "And they shall be desolate in the midst of the countries [that are] desolate, and her cities shall be in the midst of the cities [that are] wasted.", "vulgate": "et dissipabuntur in medio terrarum desolatarum et urbes eius in medio civitatum desertarum erunt;", "brenton": "And it shall be made desolate in the midst of desolate countries, and their cities shall be desolate in the midst of desolate cities:"}}, {"v": 8, "ref": "30:8", "o": "וְ/יָדְע֖וּ כִּֽי אֲנִ֣י יְהוָ֑ה בְּ/תִתִּ/י אֵ֣שׁ בְּ/מִצְרַ֔יִם וְ/נִשְׁבְּר֖וּ כָּל עֹזְרֶֽי/הָ", "en": {"kjv": "And they shall know that I am the Lord, when I have set a fire in Egypt, and when all her helpers shall be destroyed.", "web": "They shall know that I am Yahweh, when I have set a fire in Egypt, and all her helpers are destroyed.", "bsb": "Then they will know that I am the LORD when I set fire to Egypt and all her helpers are shattered.", "asv": "And they shall know that I am Jehovah, when I have set a fire in Egypt, and all her helpers are destroyed.", "ylt": "And they have known that I am Jehovah, In My giving fire against Egypt, And broken have been all her helpers.", "dra": "And they shall know that I am the Lord: when I shall have set a fire in Egypt, and all the helpers thereof shall be destroyed.", "bbe": "And they will be certain that I am the Lord, when I have put a fire in Egypt and all her helpers are broken.", "geneva": "And they shall knowe that I am the Lord, when I haue set a fire in Egypt, and when all her helpers shall be destroyed.", "wycliffe": "And thei schulen wite, that Y am the Lord God, whanne Y schal yyue fier in Egipt, and alle the helperis therof schulen be al to-brokun.", "rotherham": "So shall they know that, I am Yahweh,- By my setting a fire in Egypt, When all her helpers shall be broken.", "darby": "And they shall know that I [am] Jehovah, when I have set a fire in Egypt, and all her helpers shall be broken.", "twenty": "", "jps": "And they shall know that I am HaShem, when I have set a fire in Egypt, and all her helpers are destroyed.", "acv": "And they shall know at I am Jehovah when I have set a fire in Egypt, and all her helpers are destroyed.", "anderson": "", "haweis": "", "noyes": "And they shall know that I am Jehovah, when I have brought a fire into Egypt, and all her helpers shall be destroyed.", "webster": "And they shall know that I [am] the LORD, when I have set a fire in Egypt, and [when] all her helpers shall be destroyed.", "vulgate": "et scient quoniam ego Dominus cum dedero ignem in Aegyptum et adtriti fuerint omnes auxiliatores eius;", "brenton": "and they shall know that I am the Lord, when I shall send fire upon Egypt, and when all that help her shall be broken."}}, {"v": 9, "ref": "30:9", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יֵצְא֨וּ מַלְאָכִ֤ים מִ/לְּ/פָנַ/י֙ בַּ/צִּ֔ים לְ/הַחֲרִ֖יד אֶת כּ֣וּשׁ בֶּ֑טַח וְ/הָיְתָ֨ה חַלְחָלָ֤ה בָ/הֶם֙ בְּ/י֣וֹם מִצְרַ֔יִם כִּ֥י הִנֵּ֖ה בָּאָֽה", "en": {"kjv": "In that day shall messengers go forth from me in ships to make the careless Ethiopians afraid, and great pain shall come upon them, as in the day of Egypt: for, lo, it cometh.", "web": "In that day shall messengers go out from before me in ships to make the careless Ethiopians afraid; and there shall be anguish on them, as in the day of Egypt; for, behold, it comes.", "bsb": "On that day messengers will go out from Me in ships to frighten Cush out of complacency. Anguish will come upon them on the day of Egypt’s doom. For it is indeed coming.", "asv": "In that day shall messengers go forth from before me in ships to make the careless Ethiopians afraid; and there shall be anguish upon them, as in the day of Egypt; for, lo, it cometh.", "ylt": "In that day go forth do messengers from before Me in ships, To trouble confident Cush, And there hath been great pain among them, As the day of Egypt, for lo, it hath come.", "dra": "In that day shall messengers go forth from my face in ships to destroy the confidence of Ethiopia, and there shall be dread among them in the day of Egypt: because it shall certainly come.", "bbe": "In that day men will go out quickly to take the news, causing fear in untroubled Ethiopia; and bitter pain will come on them as in the day of Egypt; for see, it is coming.", "geneva": "In that day shall there messengers go forth from me in shippes, to make the carelesse Mores aftaide, and feare shall come vpon them, as in the day of Egypt: for loe, it commeth.", "wycliffe": "In that dai messangeris schulen go out fro my face in schippis with thre ordris of ooris, to al to-breke the trist of Ethiopie; and drede schal be in hem in the dai of Egipt, for with out doute it schal come.", "rotherham": "In that day, shall messengers go forth from before me making haste, to cause dread unto Ethiopia so confident,- And a pang shall be upon them in the day of Egypt, For lo! it cometh.", "darby": "In that day shall messengers go forth from me in ships, to make careless Ethiopia afraid; and anguish shall come upon them, as in the day of Egypt: for behold, it cometh!", "twenty": "", "jps": "In that day shall messengers go forth from before Me in ships to make the confident Ethiopians afraid; and there shall come convulsion upon them in the day of Egypt; for, lo, it cometh.", "acv": "In that day messengers shall go forth from before me in ships to make the careless Ethiopians afraid, and there shall be anguish upon them, as in the day of Egypt, for, lo, it comes.", "anderson": "", "haweis": "", "noyes": "In that day shall messengers go forth from me in ships, to make the confident Ethiopians afraid; and anguish shall come upon them, as in the day of Egypt; for behold, it cometh!", "webster": "In that day shall messengers go forth from me in ships to make the careless Cushites afraid, and great pain shall come upon them, as in the day of Egypt: for lo, it cometh.", "vulgate": "in die illa egredientur nuntii a facie mea in trieribus ad conterendam Aethiopiae confidentiam et erit pavor in eis in die Aegypti quia absque dubio veniet;", "brenton": "In that day shall messengers go forth hasting to destroy Ethiopia utterly, and there shall be tumult among them in the day of Egypt: for, behold it comes."}}, {"v": 10, "ref": "30:10", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה וְ/הִשְׁבַּתִּי֙ אֶת הֲמ֣וֹן מִצְרַ֔יִם בְּ/יַ֖ד נְבוּכַדְרֶאצַּ֥ר מֶלֶךְ בָּבֶֽל", "en": {"kjv": "Thus saith the Lord God; I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon.", "web": "Thus says the Lord Yahweh: I will also make the multitude of Egypt to cease, by the hand of Nebuchadnezzar king of Babylon.", "bsb": "This is what the Lord GOD says: I will put an end to the hordes of Egypt by the hand of Nebuchadnezzar king of Babylon.", "asv": "Thus saith the Lord Jehovah: I will also make the multitude of Egypt to cease, by the hand of Nebuchadrezzar king of Babylon.", "ylt": "Thus said the Lord Jehovah: I have caused the multitude of Egypt to cease, By the hand of Nebuchadrezzar king of Babylon,", "dra": "Thus saith the Lord God: I will make the multitude of Egypt to cease by the hand of Nabuchodonosor the king of Babylon.", "bbe": "This is what the Lord has said: I will put an end to great numbers of the people of Egypt by the hand of Nebuchadrezzar, king of Babylon.", "geneva": "Thus sayth the Lord God, I will also make the multitude of Egypt to cease by the hand of Nebuchad-nezzar King of Babel.", "wycliffe": "The Lord God seith these thingis, And I schal make to ceesse the multitude of Egipt in the hond of Nabugodonosor, king of Babiloyne.", "rotherham": "Thus, saith My Lord Yahweh,— Therefore will I cause to cease the multitude of Egypt, by the hand of Nebuchadrezzar king of Babylon:", "darby": "Thus saith the Lord Jehovah: I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon.", "twenty": "", "jps": "Thus saith the L-rd GOD: I will also make the multitude of Egypt to cease, by the hand of Nebuchadrezzar king of Babylon.", "acv": "Thus says the lord Jehovah: I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I will make the multitude of Egypt to cease by the hand of Nebuchadnezzar, the king of Babylon.", "webster": "Thus saith the Lord GOD; I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon.", "vulgate": "haec dicit Dominus Deus et cessare faciam multitudinem Aegypti in manu Nabuchodonosor regis Babylonis;", "brenton": "Thus saith the Lord God; I will also destroy the multitude of the Egyptians by the hand of Nabuchodonosor king of Babylon,"}}, {"v": 11, "ref": "30:11", "o": "ה֠וּא וְ/עַמּ֤/וֹ אִתּ/וֹ֙ עָרִיצֵ֣י גוֹיִ֔ם מֽוּבָאִ֖ים לְ/שַׁחֵ֣ת הָ/אָ֑רֶץ וְ/הֵרִ֤יקוּ חַרְבוֹתָ/ם֙ עַל מִצְרַ֔יִם וּ/מָלְא֥וּ אֶת הָ/אָ֖רֶץ חָלָֽל", "en": {"kjv": "He and his people with him, the terrible of the nations, shall be brought to destroy the land: and they shall draw their swords against Egypt, and fill the land with the slain.", "web": "He and his people with him, the terrible of the nations, shall be brought in to destroy the land; and they shall draw their swords against Egypt, and fill the land with the slain.", "bsb": "He and his people with him, the most ruthless of the nations, will be brought in to destroy the land. They will draw their swords against Egypt and fill the land with the slain.", "asv": "He and his people with him, the terrible of the nations, shall be brought in to destroy the land; and they shall draw their swords against Egypt, and fill the land with the slain.", "ylt": "He and his people with him--the terrible of nations, Are brought in to destroy the land, And they have drawn their swords against Egypt, And have filled the land with the wounded.", "dra": "He and his people with him, the strongest of nations, shall be brought to destroy the land: and they shall draw their swords upon Egypt: and shall fill the land with the slain.", "bbe": "He and the people with him, causing fear among the nations, will be sent for the destruction of the land; their swords will be let loose against Egypt and the land will be full of dead.", "geneva": "For he and his people with him, euen the terrible nations shall be brought to destroy the land: and they shall drawe their swordes against Egypt, and fill the land with the slaine.", "wycliffe": "He and his puple with hym, the strongeste men of hethene men, schulen be brouyt, to leese the lond; and thei schulen drawe out her swerdis on Egipt, and thei schulen fille the lond with slayn men.", "rotherham": "He, and his people with him the terrible ones of the nations are about to be brought in to destroy the land,- Therefore shall they unsheathe their swords against Egypt, and fill the land with the slain;", "darby": "He and his people with him, the terrible of the nations, shall be brought to destroy the land; and they shall draw their swords against Egypt, and fill the land with slain.", "twenty": "", "jps": "He and his people with him, the terrible of the nations, shall be brought in to destroy the land; and they shall draw their swords against Egypt, and fill the land with the slain.", "acv": "He and his people with him, the terrible of the nations, shall be brought in to destroy the land. And they shall draw their swords against Egypt, and fill the land with the slain.", "anderson": "", "haweis": "", "noyes": "He and his people with him, the terrible of the nations, shall be brought to make the land desolate; and they shall draw their swords against Egypt, and fill the land with the slain.", "webster": "He and his people with him, the terrible of the nations, shall be brought to destroy the land: and they shall draw their swords against Egypt, and fill the land with the slain.", "vulgate": "ipse et populus eius cum eo fortissimi gentium adducentur ad disperdendam terram et evaginabunt gladios suos super Aegyptum et implebunt terram interfectis;", "brenton": "his hand and his people's; they are plagues sent forth from the nations to destroy the land: and they all shall unsheath their swords against Egypt, and the land shall be filled with slain."}}, {"v": 12, "ref": "30:12", "o": "וְ/נָתַתִּ֤י יְאֹרִים֙ חָֽרָבָ֔ה וּ/מָכַרְתִּ֥י אֶת הָ/אָ֖רֶץ בְּ/יַד רָעִ֑ים וַ/הֲשִׁמֹּתִ֞י אֶ֤רֶץ וּ/מְלֹאָ/הּ֙ בְּ/יַד זָרִ֔ים אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "And I will make the rivers dry, and sell the land into the hand of the wicked: and I will make the land waste, and all that is therein, by the hand of strangers: I the Lord have spoken it.", "web": "I will make the rivers dry, and will sell the land into the hand of evil men; and I will make the land desolate, and all that is therein, by the hand of strangers: I, Yahweh, have spoken it.", "bsb": "I will make the streams dry up and sell the land to the wicked. By the hands of foreigners I will bring desolation upon the land and everything in it. I, the LORD, have spoken.", "asv": "And I will make the rivers dry, and will sell the land into the hand of evil men; and I will make the land desolate, and all that is therein, by the hand of strangers: I, Jehovah, have spoken it.", "ylt": "And I have made floods a dry place, And I have sold the land into the hand of evil doers, And I have made desolate the land, And its fulness, by the hand of strangers, I, Jehovah, have spoken.", "dra": "And I will make the channels of the rivers dry, and will deliver the land into the hand of the wicked: and will lay waste the land and all that is therein by the hands of strangers, I the Lord have spoken it.", "bbe": "And I will make the Nile streams dry, and will give the land into the hands of evil men, causing the land and everything in it to be wasted by the hands of men from a strange country: I the Lord have said it.", "geneva": "And I will make the riuers drye, and fell the land into the hands of the wicked, and I will make the land waste, and all that therein is by the hands of strangers: I the Lord haue spoken it.", "wycliffe": "And Y schal make drie the botmes of floodis, and Y schal yyue the lond in the hond of the worste men; and I schal distrie the lond, and the fulnesse therof in the hond of aliens; Y the Lord spak.", "rotherham": "And I will make the rivers dry, and will sell the land into the hand of wicked one.—and make the land desolate with the fulness thereof, by the hand of foreigners, I, Yahweh! have spoken.", "darby": "And I will make the rivers dry, and sell the land into the hand of the wicked; and I will make the land desolate, and all that is therein, by the hand of strangers: I Jehovah have spoken [it].", "twenty": "", "jps": "And I will make the rivers dry, and will give the land over into the hand of evil men; and I will make the land desolate, and all that is therein, by the hand of strangers; I HaShem have spoken it.", "acv": "And I will make the rivers dry, and will sell the land into the hand of evil men. And I will make the land desolate, and all that is therein, by the hand of strangers. I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "And I will make the rivers dry, and I will sell the land into the hand of evil men; and I will lay waste the land and all that is therein, by the hand of strangers; I, Jehovah, have spoken it.", "webster": "And I will make the rivers dry, and sell the land into the hand of the wicked: and I will make the land waste, and all that is in it, by the hand of strangers: I the LORD have spoken [it].", "vulgate": "et faciam alveos fluminum aridos et tradam terram in manu pessimorum et dissipabo terram et plenitudinem eius in manu alienorum ego Dominus locutus sum;", "brenton": "And I will make their rivers desolate, and will destroy the land and the fulness of it by the hands of strangers: I the Lord have spoken."}}, {"v": 13, "ref": "30:13", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה וְ/הַאֲבַדְתִּ֨י גִלּוּלִ֜ים וְ/הִשְׁבַּתִּ֤י אֱלִילִים֙ מִ/נֹּ֔ף וְ/נָשִׂ֥יא מֵ/אֶֽרֶץ מִצְרַ֖יִם לֹ֣א יִֽהְיֶה ע֑וֹד וְ/נָתַתִּ֥י יִרְאָ֖ה בְּ/אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "Thus saith the Lord God; I will also destroy the idols, and I will cause their images to cease out of Noph; and there shall be no more a prince of the land of Egypt: and I will put a fear in the land of Egypt.", "web": "Thus says the Lord Yahweh: I will also destroy the idols, and I will cause the images to cease from Memphis; and there shall be no more a prince from the land of Egypt: and I will put a fear in the land of Egypt.", "bsb": "This is what the Lord GOD says: I will destroy the idols and put an end to the images in Memphis. There will no longer be a prince in Egypt, and I will instill fear in that land.", "asv": "Thus saith the Lord Jehovah: I will also destroy the idols, and I will cause the images to cease from Memphis; and there shall be no more a prince from the land of Egypt: and I will put a fear in the land of Egypt.", "ylt": "Thus said the Lord Jehovah: And--I have destroyed idols, And caused vain things to cease from Noph, And a prince of the land of Egypt there is no more, And I give fear in the land of Egypt.", "dra": "Thus saith the Lord God: I will also destroy the idols, and I will make an end of the idols of Memphis: and there shall: be no more a prince of the land of Egypt and I will cause a terror in the land of Egypt.", "bbe": "This is what the Lord has said: In addition to this, I will give up the images to destruction and put an end to the false gods in Noph; never again will there be a ruler in the land of Egypt: and I will put a fear in the land of Egypt.", "geneva": "Thus saith the Lord God, I will also destroy the idoles, and I will cause their idoles to cease out of Noph, and there shall be no more a prince of the land of Egypt, and I will send a feare in the land of Egypt.", "wycliffe": "The Lord God seith these thingis, And Y schal leese simylacris, and Y schal make idols to ceesse fro Memphis, and a duyk of the lond of Egipt schal no more be. And Y schal yyue drede in the lond of Egipt,", "rotherham": "Thus saith My Lord Yahweh, Therefore will I destroy the manufactured gods and Cause to cease the worthless goals, out of Noph, And prince out of the land of Egypt, shall none arise any more,- And I will cause fear in the land of Egypt.", "darby": "Thus saith the Lord Jehovah: I will also destroy the idols, and I will cause the images to cease out of Noph; and there shall be no more a prince out of the land of Egypt; and I will put fear in the land of Egypt.", "twenty": "", "jps": "Thus saith the L-rd GOD: I will also destroy the idols, and I will cause the things of nought to cease from Noph; and there shall be no more a prince out of the land of Egypt; and I will put a fear in the land of Egypt.", "acv": "Thus says the lord Jehovah: I will also destroy the idols, and I will cause the images to cease from Memphis. And there shall no more be a ruler from the land of Egypt. And I will put a fear in the land of Egypt.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I will destroy the idols, and cause the images to cease out of Noph; and there shall be no more a prince of the land of Egypt; and I will bring fear upon the land of Egypt:", "webster": "Thus saith the Lord GOD; I will also destroy the idols, and I will cause [their] images to cease out of Noph; and there shall be no more a prince of the land of Egypt: and I will put a fear in the land of Egypt.", "vulgate": "haec dicit Dominus Deus et disperdam simulacra et cessare faciam idola de Memphis et dux de terra Aegypti non erit amplius et dabo terrorem in terra Aegypti;", "brenton": "For thus saith the Lord God; I will also destroy the nobles from Memphis, and the princes of Memphis out of the land of Egypt; and they shall be no more."}}, {"v": 14, "ref": "30:14", "o": "וַ/הֲשִׁמֹּתִי֙ אֶת פַּתְר֔וֹס וְ/נָתַ֥תִּי אֵ֖שׁ בְּ/צֹ֑עַן וְ/עָשִׂ֥יתִי שְׁפָטִ֖ים בְּ/נֹֽא", "en": {"kjv": "And I will make Pathros desolate, and will set fire in Zoan, and will execute judgments in No.", "web": "I will make Pathros desolate, and will set a fire in Zoan, and will execute judgments on No.", "bsb": "I will lay waste Pathros, set fire to Zoan, and execute judgment on Thebes.", "asv": "And I will make Pathros desolate, and will set a fire in Zoan, and will execute judgments upon No.", "ylt": "And I have made Pathros desolate, And I have given fire against Zoan, And I have done judgments in No,", "dra": "And I will destroy the land of Phatures, and will make a fire in Taphnis, and will execute judgments in Alexandria.", "bbe": "And I will make Pathros a waste, and put a fire in Zoan, and send my punishments on No.", "geneva": "And I will make Pathros desolate, and will set fire in Zoan, and I will execute iudgement in No.", "wycliffe": "and Y schal leese the lond of Phatures. And Y schal yyue fier in Tafnys, and Y schal make my domes in Alisaundre.", "rotherham": "Then will I bring desolation upon Pathros, and Set a fire in Zoan, and Execute judgments upon No: and", "darby": "And I will make Pathros desolate, and will set a fire in Zoan, and will execute judgment in No.", "twenty": "", "jps": "And I will make Pathros desolate, and will set a fire in Zoan, and will execute judgments in No.", "acv": "And I will make Pathros desolate, and will set a fire in Zoan, and will execute judgments upon No.", "anderson": "", "haweis": "", "noyes": "And I will lay waste Pathros, and bring a fire upon Zoan, and execute judgments upon No.", "webster": "And I will make Pathros desolate, and will set fire in Zoan, and will execute judgments in No.", "vulgate": "et disperdam terram Fatures et dabo ignem in Tafnis et faciam iudicia in Alexandriam;", "brenton": "And I will destroy the land of Phathore, and will send fire upon Tanis, and will execute vengeance on Diospolis."}}, {"v": 15, "ref": "30:15", "o": "וְ/שָׁפַכְתִּ֣י חֲמָתִ֔/י עַל סִ֖ין מָע֣וֹז מִצְרָ֑יִם וְ/הִכְרַתִּ֖י אֶת הֲמ֥וֹן נֹֽא", "en": {"kjv": "And I will pour my fury upon Sin, the strength of Egypt; and I will cut off the multitude of No.", "web": "I will pour my wrath on Sin, the stronghold of Egypt; and I will cut off the multitude of No.", "bsb": "I will pour out My wrath on Pelusium, the stronghold of Egypt, and cut off the crowds of Thebes.", "asv": "And I will pour my wrath upon Sin, the stronghold of Egypt; and I will cut off the multitude of No.", "ylt": "And I have poured out My fury on Sin, the stronghold of Egypt, And I have cut off the multitude of No.", "dra": "And I will pour out my indignation upon Pelusium the strength of Egypt, and will cut off the multitude of Alexandria.", "bbe": "I will let loose my wrath on Sin, the strong place of Egypt, cutting off the mass of the people of No.", "geneva": "And I will powre my wrath vpon Sin, which is the strength of Egypt: and I will destroy the multitude of No.", "wycliffe": "And Y schal schede out myn indignacioun on Pelusyum, the strengthe of Egipt; and Y schal sle the multitude of Alisaundre,", "rotherham": "Pour out mine indignation upon Sin the stronghold of Egypt, and Will cut off the multitude of No.", "darby": "And I will pour my fury upon Sin, the stronghold of Egypt; and I will cut off the multitude of No.", "twenty": "", "jps": "And I will pour My fury upon Sin, the stronghold of Egypt; and I will cut off the multitude of No.", "acv": "And I will pour my wrath upon Sin, the stronghold of Egypt, and I will cut off the multitude of No.", "anderson": "", "haweis": "", "noyes": "And I will pour out my fury upon Sin, the strength of Egypt, and I will cut off the multitude of No.", "webster": "And I will pour my fury upon Sin, the strength of Egypt; and I will cut off the multitude of No.", "vulgate": "et effundam indignationem meam super Pelusium robur Aegypti et interficiam multitudinem Alexandriae;", "brenton": "And I will pour out my wrath upon Sais the strength of Egypt, and will destroy the multitude of Memphis."}}, {"v": 16, "ref": "30:16", "o": "וְ/נָתַ֤תִּי אֵשׁ֙ בְּ/מִצְרַ֔יִם ח֤וּל תחיל תָּחוּל֙ סִ֔ין וְ/נֹ֖א תִּהְיֶ֣ה לְ/הִבָּקֵ֑עַ וְ/נֹ֖ף צָרֵ֥י יוֹמָֽם", "en": {"kjv": "And I will set fire in Egypt: Sin shall have great pain, and No shall be rent asunder, and Noph shall have distresses daily.", "web": "I will set a fire in Egypt: Sin shall be in great anguish, and No shall be broken up; and Memphis shall have adversaries in the daytime.", "bsb": "I will set fire to Egypt, Pelusium will writhe in anguish, Thebes will be split open, and Memphis will face daily distress.", "asv": "And I will set a fire in Egypt: Sin shall be in great anguish, and No shall be broken up; and Memphis shall have adversaries in the day-time.", "ylt": "And I have given fire against Egypt, Greatly pained is Sin, and No is to be rent, And Noph hath daily distresses.", "dra": "And I will make a fire in Egypt: Pelusium shall be in pain like a woman in labour, and Alexandria shall be laid waste, and in Memphis there shall be daily distresses.", "bbe": "And I will put a fire in Egypt; Syene will be twisting in pain, and No will be broken into, as by the onrush of waters.", "geneva": "And I will set fire in Egypt: Sin shall haue great sorowe and No shalbe destroyed, and Noph shall haue sorowes dayly.", "wycliffe": "and Y schal yyue fier in Egipt. Pelusyum, as a womman trauelynge of child, schal haue sorewe, and Alisaundre schal be destried, and in Memphis schulen be ech daies angwischis.", "rotherham": "So will I set a fire in Egypt, Sore anguish shall take Sin. And, No, shall be for rending asunder, And Noph, be in straits every day,", "darby": "And I will set a fire in Egypt: Sin shall be in great anguish, and No shall be rent asunder, and at Noph [there shall be] enemies in open day.", "twenty": "", "jps": "And I will set a fire in Egypt; Sin shall be in great convulsion, and No shall be rent asunder; and in Noph shall come adversaries in the day-time.", "acv": "And I will set a fire in Egypt. Sin shall be in great anguish, and No shall be broken up, and Memphis shall have adversaries in the daytime.", "anderson": "", "haweis": "", "noyes": "And I will bring a fire upon Egypt; Sin shall tremble, and No shall be broken through, and Noph shall be plundered by day.", "webster": "And I will set fire in Egypt: Sin shall have great pain, and No shall be rent asunder, and Noph [shall have] distresses daily.", "vulgate": "et dabo ignem in Aegypto quasi parturiens dolebit Pelusium et Alexandria erit dissipata et in Memphis angustiae cotidianae;", "brenton": "And I will send fire upon Egypt; and Syene shall be sorely troubled; and there shall be a breaking in Diospolis, and waters shall be poured out."}}, {"v": 17, "ref": "30:17", "o": "בַּח֥וּרֵי אָ֛וֶן וּ/פִי בֶ֖סֶת בַּ/חֶ֣רֶב יִפֹּ֑לוּ וְ/הֵ֖נָּה בַּ/שְּׁבִ֥י תֵלַֽכְנָה", "en": {"kjv": "The young men of Aven and of Pi–beseth shall fall by the sword: and these cities shall go into captivity.", "web": "The young men of Aven and of Pibeseth shall fall by the sword; and they shall go into captivity.", "bsb": "The young men of On and Pi-beseth will fall by the sword, and those cities will go into captivity.", "asv": "The young men of Aven and of Pi-beseth shall fall by the sword; and these cities shall go into captivity.", "ylt": "The youths of Aven and Pi-Beseth by sword do fall, And these into captivity do go.", "dra": "The young men of Heliopolis, and of Bubastus shall fall by the sword, and they themselves shall go into captivity.", "bbe": "The young men of On and Pi-beseth will be put to the sword: and these towns will be taken away prisoners.", "geneva": "The yong men of Auen, and of Phibeseth shall fall by the sworde: and these cities shall goe into captiuitie.", "wycliffe": "The yonge men of Heliopoleos and of Bubasti schulen falle doun bi swerd, and tho citees schulen be led caitifs.", "rotherham": "The young men of Aven and Pi-beseth, by the sword, shall fall; And lo! into captivity, shall they themselves wend their way.", "darby": "The young men of Aven and of Pibeseth shall fall by the sword; and these shall go into captivity.", "twenty": "", "jps": "The young men of Aven and of Pi-beseth shall fall by the sword; and these cities shall go into captivity.", "acv": "The young men of Aven and of Pi-beseth shall fall by the sword, and these cities shall go into captivity.", "anderson": "", "haweis": "", "noyes": "The young men of On and of Pibeseth shall fall by the sword, and the women shall go into captivity.", "webster": "The young men of Aven and of Pibeseth shall fall by the sword: and these [cities] shall go into captivity.", "vulgate": "iuvenes Eliupoleos et Bubasti gladio cadent et ipsae captivae ducentur;", "brenton": "The youths of Heliopolis and Bubastum shall fall by the sword, and the women shall go into captivity."}}, {"v": 18, "ref": "30:18", "o": "וּ/בִֽ/תְחַפְנְחֵס֙ חָשַׂ֣ךְ הַ/יּ֔וֹם בְּ/שִׁבְרִ/י שָׁם֙ אֶת מֹט֣וֹת מִצְרַ֔יִם וְ/נִשְׁבַּת בָּ֖/הּ גְּא֣וֹן עֻזָּ֑/הּ הִ֚יא עָנָ֣ן יְכַסֶּ֔/נָּה וּ/בְנוֹתֶ֖י/הָ בַּ/שְּׁבִ֥י תֵלַֽכְנָה", "en": {"kjv": "At Tehaphnehes also the day shall be darkened, when I shall break there the yokes of Egypt: and the pomp of her strength shall cease in her: as for her, a cloud shall cover her, and her daughters shall go into captivity.", "web": "At Tehaphnehes also the day shall withdraw itself, when I shall break there the yokes of Egypt, and the pride of her power shall cease in her: as for her, a cloud shall cover her, and her daughters shall go into captivity.", "bsb": "The day will be darkened in Tahpanhes when I break the yoke of Egypt and her proud strength comes to an end. A cloud will cover her, and her daughters will go into captivity.", "asv": "At Tehaphnehes also the day shall withdraw itself, when I shall break there the yokes of Egypt, and the pride of her power shall cease in her: as for her, a cloud shall cover her, and her daughters shall go into captivity.", "ylt": "And in Tehaphnehes hath the day been dark, In My breaking there the yokes of Egypt, And ceased in her hath the excellency of her strength, She--a cloud doth cover her, And her daughters into captivity do go.", "dra": "And in Taphnis the day shall be darkened, when I shall break there the sceptres of Egypt, and the pride of her power shall cease in her: a cloud shall cover her, and her daughters shall be led into captivity.", "bbe": "And at Tehaphnehes the day will become dark, when the yoke of Egypt is broken there, and the pride of her power comes to an end: as for her, she will be covered with a cloud, and her daughters will be taken away prisoners.", "geneva": "At Tehaphnehes the day shall restraine his light, when I shall breake there the barres of Egypt: and when the pompe of her power shall cease in her, the cloude shall couer her, and her daughters shall goe into captiuitie.", "wycliffe": "And in Thafnys the dai schal wexe blak, whanne Y schal al to-breke there the ceptris of Egipt, and the pride of the power therof schal faile there ynne. A cloude schal hile it; forsothe the douytris therof schulen be led in to caitifte, and Y schal make domes in Egipt;", "rotherham": "And in Tehaphnehes, hath the day become dark, Because I have broken, there the yoke-bars of Egypt, And there shall be made to cease therein the pride of her strength,— She, a cloud, shall cover her! And her daughters into captivity, shall wend their way.", "darby": "And at Tehaphnehes the day shall be darkened, when I break there the yokes of Egypt, and the pride of her strength shall cease in her; as for her, a cloud shall cover her, and her daughters shall go into captivity.", "twenty": "", "jps": "At Tehaphnehes also the day shall withdraw itself, when I shall break there the yokes of Egypt, and the pride of her power shall cease in her; as for her, a cloud shall cover her, and her daughters shall go into captivity.", "acv": "At Tehaphnehes also the day shall withdraw itself when I shall break the yokes of Egypt there, and the pride of her power shall cease in her. As for her, a cloud shall cover her, and her daughters shall go into captivity.", "anderson": "", "haweis": "", "noyes": "At Tahpanhes also the day shall be darkened, when I shall break there the yoke of Egypt, and the pride of her strength shall cease within her. A cloud shall cover her, and her daughters shall go into captivity.", "webster": "At Tehaphnehes also the day shall be darkened, when I shall break there the yokes of Egypt: and the pomp of her strength shall cease in her: as for her, a cloud shall cover her, and her daughters shall go into captivity.", "vulgate": "et in Tafnis nigrescet dies cum contrivero ibi sceptra Aegypti et defecerit in ea superbia potentiae eius ipsam nubes operiet filiae autem eius in captivitatem ducentur;", "brenton": "And the day shall be darkened in Taphnae, when I have broken there the scepters of Egypt: and the pride of her strength shall perish there: and a cloud shall cover her, and her daughters shall be taken prisoners."}}, {"v": 19, "ref": "30:19", "o": "וְ/עָשִׂ֥יתִי שְׁפָטִ֖ים בְּ/מִצְרָ֑יִם וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Thus will I execute judgments in Egypt: and they shall know that I am the Lord.", "web": "Thus will I execute judgments on Egypt; and they shall know that I am Yahweh.", "bsb": "So I will execute judgment on Egypt, and they will know that I am the LORD.”", "asv": "Thus will I execute judgments upon Egypt; and they shall know that I am Jehovah.", "ylt": "And I have done judgments in Egypt, And they have known that I am Jehovah.'", "dra": "And I will execute judgments in Egypt: and they shall know that I am the Lord.", "bbe": "And I will send my punishments on Egypt: and they will be certain that I am the Lord.", "geneva": "Thus will I execute iudgements in Egypt, and they shall knowe that I am the Lord.", "wycliffe": "and thei schulen wite, that Y am the Lord.", "rotherham": "Thus will I execute judgments on Egypt; And they shall know that, I, am Yahweh.", "darby": "Thus will I execute judgments in Egypt; and they shall know that I [am] Jehovah.", "twenty": "", "jps": "Thus will I execute judgments in Egypt; and they shall know that I am HaShem.'", "acv": "Thus I will execute judgments upon Egypt, and they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus will I execute judgments upon Egypt; and they shall know that I am Jehovah.", "webster": "Thus will I execute judgments in Egypt: and they shall know that I [am] the LORD.", "vulgate": "et faciam iudicia in Aegypto et scient quia ego Dominus;", "brenton": "And I will execute judgment on Egypt; and they shall know that I am the Lord."}}, {"v": 20, "ref": "30:20", "o": "וַ/יְהִ֗י בְּ/אַחַ֤ת עֶשְׂרֵה֙ שָׁנָ֔ה בָּֽ/רִאשׁ֖וֹן בְּ/שִׁבְעָ֣ה לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass in the eleventh year, in the first month, in the seventh day of the month, that the word of the Lord came unto me, saying,", "web": "In the eleventh year, in the first month, in the seventh day of the month, Yahweh’s word came to me, saying,", "bsb": "In the eleventh year, on the seventh day of the first month, the word of the LORD came to me, saying,", "asv": "And it came to pass in the eleventh year, in the firstmonth, in the seventhdayof the month, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the eleventh year, in the first month , in the seventh of the month, hath a word of Jehovah been unto me, saying: `Son of man,", "dra": "And it came to pass in the eleventh year, in the first month, in the seventh day of the month, that the word of the Lord came, me, saying:", "bbe": "Now in the eleventh year, in the first month, on the seventh day of the month, the word of the Lord came to me, saying,", "geneva": "And in the eleuenth yeere, in the first moneth, and in the seuenth day of the moneth, the worde of the Lord came vnto me, saying,", "wycliffe": "And it was doon in the enleuenthe yeer, in the firste monethe, in the seuenthe dai of the moneth, the word of the Lord was maad to me,", "rotherham": "And it came to pass in the eleventh year in the first month on the seventh of the month, that the word of Yahweh came unto me saying:", "darby": "And it came to pass in the eleventh year, in the first [month], on the seventh of the month, the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass in the eleventh year, in the first month, in the seventh day of the month, that the word of HaShem came unto me, saying:", "acv": "And it came to pass in the eleventh year, in the first month, in the seventh day of the month, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Now it came to pass in the eleventh year, in the first month, on the seventh day of the month, that the word of Jehovah came to me, saying:", "webster": "And it came to pass in the eleventh year, in the first [month], in the seventh [day] of the month, [that] the word of the LORD came to me, saying,", "vulgate": "et factum est in undecimo anno in primo in septima mensis factum est verbum Domini ad me dicens;", "brenton": "And it came to pass in the eleventh year, in the first month, on the seventh day of the month, the word of the Lord came to me, saying,"}}, {"v": 21, "ref": "30:21", "o": "בֶּן אָדָ֕ם אֶת זְר֛וֹעַ פַּרְעֹ֥ה מֶֽלֶךְ מִצְרַ֖יִם שָׁבָ֑רְתִּי וְ/הִנֵּ֣ה לֹֽא חֻ֠בְּשָׁה לָ/תֵ֨ת רְפֻא֜וֹת לָ/שׂ֥וּם חִתּ֛וּל לְ/חָבְשָׁ֥/הּ לְ/חָזְקָ֖/הּ לִ/תְפֹּ֥שׂ בֶּ/חָֽרֶב", "en": {"kjv": "Son of man, I have broken the arm of Pharaoh king of Egypt; and, lo, it shall not be bound up to be healed, to put a roller to bind it, to make it strong to hold the sword.", "web": "Son of man, I have broken the arm of Pharaoh king of Egypt; and behold, it has not been bound up, to apply medicines, to put a bandage to bind it, that it be strong to hold the sword.", "bsb": "“Son of man, I have broken the arm of Pharaoh king of Egypt. See, it has not been bound up for healing, or splinted for strength to hold the sword.", "asv": "Son of man, I have broken the arm of Pharaoh king of Egypt; and, lo, it hath not been bound up, to apply healing medicines, to put a bandage to bind it, that it be strong to hold the sword.", "ylt": "The arm of Pharaoh, king of Egypt, I have broken, And lo, it hath not been bound up to give healing, To put a bandage to bind it, To strengthen it--to lay hold on the sword.", "dra": "Son of man, I have broken the arm of Pharao king of Egypt: and behold it is not bound up, to be healed, to be tied up with clothes, and swathed with linen, that it might recover strength, and hold the sword.", "bbe": "Son of man, the arm of Pharaoh, king of Egypt, has been broken by me, and no band has been put round it to make it well, no band has been twisted round it to make it strong for gripping the sword.", "geneva": "Sonne of man, I haue broken the arme of Pharaoh King of Egypt: and lo, it shall not be boud vp to be healed, neither shall they put a roule to bind it, and so make it strong, to hold the sworde.", "wycliffe": "and he seide, Thou sone of man, Y haue broke the arm of Farao, kyng of Egipt; and lo! it is not wlappid, that helthe schulde be restorid therto, that it schulde be boundun with clothis, and woundun with lynnun clothis, and that he myyte holde swerd, whanne he hadde resseyued strengthe.", "rotherham": "Son of man, The arm of Pharaoh king of Egypt, have I broken,- And lo! it hath not been bound up-To apply healing remedies To put on a bandage for binding it up. To make it strong to grasp the sword.", "darby": "Son of man, I have broken the arm of Pharaoh king of Egypt; and behold, it shall not be bound up to apply remedies, to put a bandage to bind it, to make it strong to hold the sword.", "twenty": "", "jps": "'Son of man, I have broken the arm of Pharaoh king of Egypt; and, lo, it hath not been bound up to be healed, to put a roller, that it be bound up and wax strong, that it hold the sword.", "acv": "Son of man, I have broken the arm of Pharaoh king of Egypt. And, lo, it has not been bound up, to apply medicines, to put a bandage to bind it, that it be strong to hold the sword.", "anderson": "", "haweis": "", "noyes": "Son of man, I have broken the arm of Pharaoh, king of Egypt, and lo, it is not bound up, so as to have medicines applied to it; a bandage is not applied to it, to make it strong to hold the sword.", "webster": "Son of man, I have broken the arm of Pharaoh king of Egypt; and lo, it shall not be bound up to be healed, to put a roller to bind it, to make it strong to hold the sword.", "vulgate": "fili hominis brachium Pharao regis Aegypti confregi et ecce non est obvolutum ut restitueretur ei sanitas ut ligaretur pannis et farciretur linteolis et recepto robore posset tenere gladium;", "brenton": "Son of man, I have broken the arms of Pharao, king of Egypt; and, behold, it has not been bound up to be healed, to have a plaster put upon it, or to be strengthened to lay hold of the sword."}}, {"v": 22, "ref": "30:22", "o": "לָ/כֵ֞ן כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה הִנְ/נִי֙ אֶל פַּרְעֹ֣ה מֶֽלֶךְ מִצְרַ֔יִם וְ/שָֽׁבַרְתִּי֙ אֶת זְרֹ֣עֹתָ֔י/ו אֶת הַ/חֲזָקָ֖ה וְ/אֶת הַ/נִּשְׁבָּ֑רֶת וְ/הִפַּלְתִּ֥י אֶת הַ/חֶ֖רֶב מִ/יָּדֽ/וֹ", "en": {"kjv": "Therefore thus saith the Lord God; Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong, and that which was broken; and I will cause the sword to fall out of his hand.", "web": "Therefore thus says the Lord Yahweh: Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong arm, and that which was broken; and I will cause the sword to fall out of his hand.", "bsb": "Therefore this is what the Lord GOD says: Behold, I am against Pharaoh king of Egypt. I will break his arms, both the strong one and the one already broken, and will make the sword fall from his hand.", "asv": "Therefore thus saith the Lord Jehovah: Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong arm, and that which was broken; and I will cause the sword to fall out of his hand.", "ylt": "Therefore, thus said the Lord Jehovah: Lo, I am against Pharaoh, king of Egypt, And I have broken his arms, The strong one and the broken one, And have caused the sword to fall out of his hand,", "dra": "Therefore, thus saith the Lord God: Behold, I come against Pharao king of Egypt, and I will break into pieces his strong arm, which is already broken: and I will cause the sword to fall out of his hand:", "bbe": "For this cause the Lord has said: See, I am against Pharaoh, king of Egypt, and by me his strong arm will be broken; and I will make the sword go out of his hand.", "geneva": "Therefore thus saith the Lord God, Behold, I come against Pharaoh King of Egypt, and will breake his arme, that was strong, but is broken, and I will cause the sworde to fall out of his hande.", "wycliffe": "Therfor the Lord God seith these thingis, Lo! Y to Farao, king of Egipt; and Y schal make lesse his strong arm but brokun, and Y schal caste doun the swerd fro his hond.", "rotherham": "Therefore, Thus, saith My Lord Yahweh-Behold me! against Pharaoh king of Egypt, Therefore will I break his arms, That which is strong, and That which is broken,- So will I cause the sword to fall out of his hand.", "darby": "Therefore thus saith the Lord Jehovah: Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong one, and that which was broken; and I will cause the sword to fall out of his hand.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong, and that which was broken; and I will cause the sword to fall out of his hand.", "acv": "Therefore thus says the lord Jehovah: Behold, I am against Pharaoh king of Egypt. And I will break his arms, the strong arm, and that which was broken, and I will cause the sword to fall out of his hand.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, I am against Pharaoh, the king of Egypt; and I will break his arms, both the strong one, and that which was broken, and I will cause the sword to fall out of his hand.", "webster": "Therefore thus saith the Lord GOD; Behold, I [am] against Pharaoh king of Egypt, and will break his arms, the strong, and that which was broken; and I will cause the sword to fall out of his hand.", "vulgate": "propterea haec dicit Dominus Deus ecce ego ad Pharao regem Aegypti et comminuam brachium eius forte sed confractum et deiciam gladium de manu eius;", "brenton": "Therefore thus saith the Lord God; Behold, I am against Pharao king of Egypt, and I will break his strong and outstretched arms, and will smite down his sword out of his hand."}}, {"v": 23, "ref": "30:23", "o": "וַ/הֲפִצוֹתִ֥י אֶת מִצְרַ֖יִם בַּ/גּוֹיִ֑ם וְ/זֵרִיתִ֖/ם בָּ/אֲרָצֽוֹת", "en": {"kjv": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "web": "I will scatter the Egyptians among the nations, and will disperse them through the countries.", "bsb": "I will disperse the Egyptians among the nations and scatter them throughout the lands.", "asv": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "ylt": "And scattered the Egyptians among nations, And I have spread them through lands,", "dra": "And I will disperse Egypt among the nations, and scatter them through the countries.", "bbe": "And I will send the Egyptians in flight among the nations and wandering through the countries.", "geneva": "And I will scatter the Egyptians among the nations, and will disperse them through the countreys.", "wycliffe": "And Y schal scatere Egipt among hethene men, and Y schal wyndewe hem in londis.", "rotherham": "And I will disperse the Egyptians among the nations,— And scatter them throughout the lands;", "darby": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "twenty": "", "jps": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "acv": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "anderson": "", "haweis": "", "noyes": "And I will scatter the Egyptians among the nations, and disperse them through the countries.", "webster": "And I will scatter the Egyptians among the nations, and will disperse them through the countries.", "vulgate": "et dispergam Aegyptum in gentibus et ventilabo eos in terris;", "brenton": "And I will disperse the Egyptians among the nations, and will utterly scatter them among the countries."}}, {"v": 24, "ref": "30:24", "o": "וְ/חִזַּקְתִּ֗י אֶת זְרֹעוֹת֙ מֶ֣לֶךְ בָּבֶ֔ל וְ/נָתַתִּ֥י אֶת חַרְבִּ֖/י בְּ/יָד֑/וֹ וְ/שָׁבַרְתִּי֙ אֶת זְרֹע֣וֹת פַּרְעֹ֔ה וְ/נָאַ֛ק נַאֲק֥וֹת חָלָ֖ל לְ/פָנָֽי/ו", "en": {"kjv": "And I will strengthen the arms of the king of Babylon, and put my sword in his hand: but I will break Pharaoh’s arms, and he shall groan before him with the groanings of a deadly wounded man.", "web": "I will strengthen the arms of the king of Babylon, and put my sword in his hand: but I will break the arms of Pharaoh, and he shall groan before him with the groaning of a mortally wounded man.", "bsb": "I will strengthen the arms of Babylon’s king and place My sword in his hand, but I will break the arms of Pharaoh, who will groan before him like a mortally wounded man.", "asv": "And I will strengthen the arms of the king of Babylon, and put my sword in his hand: but I will break the arms of Pharaoh, and he shall groan before him with the groanings of a deadly wounded man.", "ylt": "And strengthened the arms of the king of Babylon, And I have given My sword into his hand, And I have broken the arms of Pharaoh, And he hath groaned the groans of a pierced one--before him.", "dra": "And I will strengthen the arms of the king of Babylon, and will put my sword in his hand: and I will break the arms of Pharao, and they shall groan bitterly being slain before his face.", "bbe": "And I will make the arms of the king of Babylon strong, and will put my sword in his hand: but Pharaoh's arms will be broken, and he will give cries of pain before him like the cries of a man wounded to death.", "geneva": "And I will strengthen the arme of the King of Babel, and put my sworde in his hand, but I will breake Pharaohs armes, and he shall cast out sighings, as the sighings of him, that is wounded before him.", "wycliffe": "And Y schal coumforte the armes of the kyng of Babiloyne, and Y schal yyue my swerd in the hond of hym; and Y schal breke the armes of Farao, and men slayn bifore his face schulen weile bi weilyngis.", "rotherham": "And will uphold the arms of the king of Babylon, And put my sword into his hand,- And will break the arms of Pharaoh, And he shall utter the groans of one thrust through, before him.", "darby": "And I will strengthen the arms of the king of Babylon, and put my sword in his hand; and I will break Pharaoh's arms, so that he shall groan before him with the groanings of a deadly-wounded [man].", "twenty": "", "jps": "And I will strengthen the arms of the king of Babylon, and put My sword in his hand; but I will break the arms of Pharaoh, and he shall groan before him with the groanings of a deadly wounded man.", "acv": "And I will strengthen the arms of the king of Babylon, and put my sword in his hand. But I will break the arms of Pharaoh, and he shall groan before him with the groanings of a mortally wounded man.", "anderson": "", "haweis": "", "noyes": "But I will strengthen the arms of the king of Babylon, and will put my sword into his hand, and break the arms of Pharaoh, so that he shall groan before him with the groanings of a deadly wounded man.", "webster": "And I will strengthen the arms of the king of Babylon, and put my sword in his hand: but I will break Pharaoh's arms, and he shall groan before him with the groanings of a deadly wounded [man].", "vulgate": "et confortabo brachia regis Babylonis daboque gladium meum in manu eius et confringam brachia Pharaonis et gement gemitibus interfecti coram facie eius;", "brenton": "And I will strengthen the arms of the king of Babylon, and put my sword into his hand: and he shall bring it upon Egypt, and shall take her plunder and seize her spoils."}}, {"v": 25, "ref": "30:25", "o": "וְ/הַחֲזַקְתִּ֗י אֶת זְרֹעוֹת֙ מֶ֣לֶךְ בָּבֶ֔ל וּ/זְרֹע֥וֹת פַּרְעֹ֖ה תִּפֹּ֑לְנָה וְֽ/יָדְע֞וּ כִּֽי אֲנִ֣י יְהוָ֗ה בְּ/תִתִּ֤/י חַרְבִּ/י֙ בְּ/יַ֣ד מֶֽלֶךְ בָּבֶ֔ל וְ/נָטָ֥ה אוֹתָ֖/הּ אֶל אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "But I will strengthen the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I am the Lord, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "web": "I will hold up the arms of the king of Babylon; and the arms of Pharaoh shall fall down; and they shall know that I am Yahweh, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out on the land of Egypt.", "bsb": "I will strengthen the arms of Babylon’s king, but Pharaoh’s arms will fall limp. Then they will know that I am the LORD, when I place My sword in the hand of Babylon’s king, and he wields it against the land of Egypt.", "asv": "And I will hold up the arms of the king of Babylon; and the arms of Pharaoh shall fall down; and they shall know that I am Jehovah, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "ylt": "And I have strengthened the arms of the king of Babylon, And the arms of Pharaoh do fall down, And they have known that I am Jehovah, In My giving My sword into the hand of the king of Babylon, And he hath stretched it out toward the land of Egypt.", "dra": "And I will strengthen the arms of the king of Babylon, and the arms of Pharao shall fall: and they shall know that I am the Lord, when I shall have given my sword into the hand of the king of Babylon, and he shall have stretched it forth upon the land of Egypt.", "bbe": "And I will make the arms of the king of Babylon strong, and the arms of Pharaoh will be hanging down; and they will be certain that I am the Lord, when I put my sword into the hand of the king of Babylon and it is stretched out against the land of Egypt.", "geneva": "But I will strengthen the armes of the king of Babel, and the armes of Pharaoh shall fall downe, and they shall knowe, that I am the Lord, when I shall put my sworde into the hand of the King of Babel, and he shall stretch it out vpon the land of Egypt.", "wycliffe": "And Y schal coumforte the armes of the kyng of Babiloyne, and the armes of Farao schulen falle doun. And thei schulen wite, that Y am the Lord, whanne Y schal yyue my swerd in the hond of the kyng of Babiloyne; and he schal stretche forth it on the lond of Egipt.", "rotherham": "Yea I will uphold the arms of the king of Babylon, But the arms of Pharaoh shall fall, And they shall know that I am Yahweh By my putting my sword into the hand of the king of Babylon, And he shall stretch it out against the land of Egypt.", "darby": "And I will strengthen the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I [am] Jehovah, when I have put my sword into the hand of the king of Babylon, and he shall have stretched it out upon the land of Egypt.", "twenty": "", "jps": "And I will hold up the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I am HaShem, when I shall put My sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "acv": "And I will hold up the arms of the king of Babylon, and the arms of Pharaoh shall fall down. And they shall know that I am Jehovah when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "anderson": "", "haweis": "", "noyes": "Yea, I will strengthen the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I am Jehovah, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "webster": "But I will strengthen the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I [am] the LORD, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.", "vulgate": "et confortabo brachia regis Babylonis et brachia Pharaonis concident et scient quia ego Dominus cum dedero gladium meum in manu regis Babylonis et extenderit eum super terram Aegypti;", "brenton": "Yea, I will strengthen the arms of the king of Babylon, and the arms of Pharao shall fail: and they shall know that I am the Lord, when I have put my sword into the hands of the king of Babylon, and he shall stretch it out over the land of Egypt."}}, {"v": 26, "ref": "30:26", "o": "וַ/הֲפִצוֹתִ֤י אֶת מִצְרַ֨יִם֙ בַּ/גּוֹיִ֔ם וְ/זֵרִיתִ֥י אוֹתָ֖/ם בָּ/אֲרָצ֑וֹת וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will scatter the Egyptians among the nations, and disperse them among the countries; and they shall know that I am the Lord.", "web": "I will scatter the Egyptians among the nations, and disperse them through the countries; and they shall know that I am Yahweh.", "bsb": "I will disperse the Egyptians among the nations and scatter them throughout the lands. Then they will know that I am the LORD.”", "asv": "And I will scatter the Egyptians among the nations, and disperse them through the countries; and they shall know that I am Jehovah.", "ylt": "And I have scattered the Egyptians among nations, And I have spread them through lands, And they have known that I am Jehovah!'", "dra": "And I will disperse Egypt among the nations, and will scatter them through the countries, and they shall know that I am the Lord.", "bbe": "And I will send the Egyptians in flight among the nations and wandering through the countries; and they will be certain that I am the Lord.", "geneva": "And I will scatter the Egyptians among the nations, and disperse them among ye countreys, and they shall knowe, that I am the Lord.", "wycliffe": "And Y schal scatere Egipt in to naciouns, and Y schal wyndewe hem in to londis; and thei schulen wite, that Y am the Lord.", "rotherham": "So will I disperse the Egyptians among the nations, And scatter them throughout the lands, And they shall know that, I, am Yahweh.", "darby": "And I will scatter the Egyptians among the nations, and disperse them through the countries: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "And I will scatter the Egyptians among the nations, and disperse them through the countries; and they shall know that I am HaShem.'", "acv": "And I will scatter the Egyptians among the nations, and disperse them through the countries. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will scatter the Egyptians among the nations, and disperse them among the countries, and they shall know that I am Jehovah.", "webster": "And I will scatter the Egyptians among the nations, and disperse them among the countries; and they shall know that I [am] the LORD.", "vulgate": "et dispergam Aegyptum in nationes et ventilabo eos in terris et scient quia ego Dominus;", "brenton": "And I will disperse the Egyptians among the nations, and utterly scatter them among the countries; and they all shall know that I am the Lord."}}]}, {"c": 31, "verses": [{"v": 1, "ref": "31:1", "o": "וַ/יְהִ֗י בְּ/אַחַ֤ת עֶשְׂרֵה֙ שָׁנָ֔ה בַּ/שְּׁלִישִׁ֖י בְּ/אֶחָ֣ד לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass in the eleventh year, in the third month, in the first day of the month, that the word of the Lord came unto me, saying,", "web": "In the eleventh year, in the third month, in the first day of the month, Yahweh’s word came to me, saying,", "bsb": "In the eleventh year, on the first day of the third month, the word of the LORD came to me, saying,", "asv": "And it came to pass in the eleventh year, in the thirdmonth, in the firstdayof the month, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the eleventh year, in the third month , in the first of the month, hath a word of Jehovah been unto me, saying:", "dra": "And it came to pass, in the eleventh year, the third month the first day of the month, that the word of the Lord came to me, saying:", "bbe": "Now in the eleventh year, in the third month, on the first day of the month, the word of the Lord came to me, saying,", "geneva": "And in the eleuenth yeere, in the third moneth, and in the first day of the moneth the worde of the Lord came vnto me, saying,", "wycliffe": "And it was don in the enleuenthe yeer, in the thridde moneth, in the firste dai of the monethe, the word of the Lord was maad to me,", "rotherham": "And it came to pass in the eleventh year, in the third month, on the first of the month, that the word of Yahweh came unto me, saying:", "darby": "And it came to pass in the eleventh year, in the third [month], on the first of the month, [that] the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass in the eleventh year, in the third month, in the first day of the month, that the word of HaShem came unto me, saying:", "acv": "And it came to pass in the eleventh year, in the third month, in the first day of the month, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Now it came to pass in the eleventh year, in the third month, on the first day of the month, that the word of Jehovah came to me, saying:", "webster": "And it came to pass in the eleventh year, in the third [month], in the first [day] of the month, [that] the word of the LORD came to me, saying,", "vulgate": "et factum est in undecimo anno tertio una mensis factum est verbum Domini ad me dicens;", "brenton": "And it came to pass in the eleventh year, in the third month, on the first day of the month, the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "31:2", "o": "בֶּן אָדָ֕ם אֱמֹ֛ר אֶל פַּרְעֹ֥ה מֶֽלֶךְ מִצְרַ֖יִם וְ/אֶל הֲמוֹנ֑/וֹ אֶל מִ֖י דָּמִ֥יתָ בְ/גָדְלֶֽ/ךָ", "en": {"kjv": "Son of man, speak unto Pharaoh king of Egypt, and to his multitude; Whom art thou like in thy greatness?", "web": "Son of man, tell Pharaoh king of Egypt, and to his multitude: Whom are you like in your greatness?", "bsb": "“Son of man, say to Pharaoh king of Egypt and to his multitude: ‘Who can be compared to your greatness?", "asv": "Son of man, say unto Pharaoh king of Egypt, and to his multitude: Whom art thou like in thy greatness?", "ylt": "`Son of man, say unto Pharaoh king of Egypt, and unto his multitude: To whom hast thou been like in thy greatness?", "dra": "Son of man, speak to Pharao king of Egypt, and to his people: To whom art thou like in thy greatness?", "bbe": "Son of man, say to Pharaoh, king of Egypt, and to his people; Whom are you like in your great power?", "geneva": "Sonne of man, speake vnto Pharaoh King of Egypt, and to his multitude, Whom art thou like in thy greatnesse?", "wycliffe": "and he seide, Thou, sone of man, seie to Farao, kyng of Egipt, and to his puple, To whom art thou maad lijk in thi greetnesse?", "rotherham": "Son of man Say unto Pharaoh king of Egypt and unto his multitude,— Whom art thou like in thy greatness?", "darby": "Son of man, say unto Pharaoh king of Egypt, and to his multitude: Whom art thou like in thy greatness?", "twenty": "", "jps": "'Son of man, say unto Pharaoh king of Egypt, and to his multitude: whom art thou like in thy greatness?", "acv": "Son of man, say to Pharaoh king of Egypt, and to his multitude, Whom are thou like in thy greatness?", "anderson": "", "haweis": "", "noyes": "Son of man, say to Pharaoh, king of Egypt, and to his multitude: To whom art thou like in thy greatness?", "webster": "Son of man, speak to Pharaoh king of Egypt, and to his multitude; Whom art thou like in thy greatness?", "vulgate": "fili hominis dic Pharaoni regi Aegypti et populo eius cui similis factus es in magnitudine tua;", "brenton": "Son of man, say to Pharao king of Egypt, and to his multitude; To whom hast thou compared thyself in thy haughtiness?"}}, {"v": 3, "ref": "31:3", "o": "הִנֵּ֨ה אַשּׁ֜וּר אֶ֣רֶז בַּ/לְּבָנ֗וֹן יְפֵ֥ה עָנָ֛ף וְ/חֹ֥רֶשׁ מֵצַ֖ל וּ/גְבַ֣הּ קוֹמָ֑ה וּ/בֵ֣ין עֲבֹתִ֔ים הָיְתָ֖ה צַמַּרְתּֽ/וֹ", "en": {"kjv": "Behold, the Assyrian was a cedar in Lebanon with fair branches, and with a shadowing shroud, and of an high stature; and his top was among the thick boughs.", "web": "Behold, the Assyrian was a cedar in Lebanon with beautiful branches, and with a forest-like shade, and of high stature; and its top was among the thick boughs.", "bsb": "Look at Assyria, a cedar in Lebanon, with beautiful branches that shaded the forest. It towered on high; its top was among the clouds.", "asv": "Behold, the Assyrian was a cedar in Lebanon with fair branches, and with a forest-like shade, and of high stature; and its top was among the thick boughs.", "ylt": "Lo, Asshur, a cedar in Lebanon, Fair in branch, and shading bough, and high in stature, And between thickets hath its foliage been.", "dra": "Behold, the Assyrian like a cedar in Libanus, with fair branches, and full of leaves, of a high stature, and his top was elevated among the thick boughs.", "bbe": "See, a pine-tree with beautiful branches and thick growth, giving shade and very tall; and its top was among the clouds.", "geneva": "Beholde, Asshur was like a cedar in Lebanon with faire branches, and with thicke shadowing boughes, and shot vp very hye, and his toppe was among the thicke boughes.", "wycliffe": "Lo! Assur as a cedre in Liban, fair in braunchis, and ful of boowis, and hiy bi hiynesse; and his heiyte was reisid among thicke bowis.", "rotherham": "Lo! Assyria, was a cedar in Lebanon, Beautiful in bough and Dense in foliage and Lofty in stature,— and Among the clouds, came to be his top:", "darby": "Behold, Assyria was a cedar in Lebanon, with fair branches and a shadowing shroud, and of a high stature: and his top was amidst the thick boughs.", "twenty": "", "jps": "Behold, the Assyrian was a cedar in Lebanon, with fair branches, and with a shadowing shroud, and of a high stature; and its top was among the thick boughs.", "acv": "Behold, the Assyrian was a cedar in Lebanon with fair branches, and with a forest-like shade, and of high stature, and its top was among the thick boughs.", "anderson": "", "haweis": "", "noyes": "Behold, the Assyrian was a cedar upon Lebanon, with fair branches; An overshadowing thicket, high of stature; And his top was among thick boughs.", "webster": "Behold, the Assyrian [was] a cedar in Lebanon with fair branches, and with a shady cover, and of a high stature; and his top was among the thick boughs.", "vulgate": "ecce Assur quasi cedrus in Libano pulcher ramis et frondibus nemorosus excelsusque altitudine et inter condensas frondes elevatum est cacumen eius;", "brenton": "Behold, the Assyrian was a cypress in Libanus, and was fair in shoots, and high in stature: his top reached to the midst of the clouds."}}, {"v": 4, "ref": "31:4", "o": "מַ֣יִם גִּדְּל֔וּ/הוּ תְּה֖וֹם רֹֽמְמָ֑תְ/הוּ אֶת נַהֲרֹתֶ֗י/הָ הֹלֵךְ֙ סְבִיב֣וֹת מַטָּעָ֔/הּ וְ/אֶת תְּעָלֹתֶ֣י/הָ שִׁלְחָ֔ה אֶ֖ל כָּל עֲצֵ֥י הַ/שָּׂדֶֽה", "en": {"kjv": "The waters made him great, the deep set him up on high with her rivers running round about his plants, and sent out her little rivers unto all the trees of the field.", "web": "The waters nourished it, the deep made it to grow: its rivers ran all around its plantation; and it sent out its channels to all the trees of the field.", "bsb": "The waters made it grow; the deep springs made it tall, directing their streams all around its base and sending their channels to all the trees of the field.", "asv": "The waters nourished it, the deep made it to grow: the rivers thereof ran round about its plantation; and it sent out its channels unto all the trees of the field.", "ylt": "Waters have made it great, The deep hath exalted him with its flowings, Going round about its planting, And its conduits it hath sent forth unto all trees of the field.", "dra": "The waters nourished him, the deep set him tip on high, the streams thereof ran round about his roots, and it sent, forth its rivulets to all the trees of the country.", "bbe": "It got strength from the waters and the deep made it tall: its streams went round about its planted land and it sent out its waterways to all the trees of the field.", "geneva": "The waters nourished him, and the deepe exalted him on hie with her riuers running round about his plants, and sent out her litle riuers vnto all the trees of the fielde.", "wycliffe": "Watris nurschiden hym, the depthe of watris enhaunside him; hise floodis fletiden out in the cumpas of hise rootis, and he sente out hise strondis to alle the trees of the cuntrei.", "rotherham": "The waters made him great, the roaring deep, made him high—with its currents going round about the place where it was planted, Its channels also, it sent forth unto all the trees of the field.", "darby": "The waters made him great, the deep set him up on high; its streams ran round about his plantation, and it sent out its rivulets unto all the trees of the field.", "twenty": "", "jps": "The waters nourished it, the deep made it to grow; her rivers ran round about her plantation, and she sent out her conduits unto all the trees of the field.", "acv": "The waters nourished it. The deep made it to grow. The rivers of it ran round about its plantation, and it sent out its channels to all the trees of the field.", "anderson": "", "haweis": "", "noyes": "The waters made him great; the deep waters made him high; Their streams went around their plantation, And sent forth their channels to all the trees of the field.", "webster": "The waters made him great, the deep set him up on high with her rivers running round his plants, and sent out her little rivers to all the trees of the field.", "vulgate": "aquae nutrierunt illum abyssus exaltavit eum flumina eius manabant in circuitu radicum eius et rivos suos emisit ad universa ligna regionis;", "brenton": "The water nourished him, the depth made him grow tall; she led her rivers round about his plants, and she sent forth her streams to all the trees of the field."}}, {"v": 5, "ref": "31:5", "o": "עַל כֵּן֙ גָּבְהָ֣א קֹמָת֔/וֹ מִ/כֹּ֖ל עֲצֵ֣י הַ/שָּׂדֶ֑ה וַ/תִּרְבֶּ֨ינָה סַֽרְעַפֹּתָ֜י/ו וַ/תֶּאֱרַ֧כְנָה פארת/ו פֹארֹתָ֛י/ו מִ/מַּ֥יִם רַבִּ֖ים בְּ/שַׁלְּחֽ/וֹ", "en": {"kjv": "Therefore his height was exalted above all the trees of the field, and his boughs were multiplied, and his branches became long because of the multitude of waters, when he shot forth.", "web": "Therefore its stature was exalted above all the trees of the field; and its boughs were multiplied, and its branches became long by reason of many waters, when it spread them out.", "bsb": "Therefore it towered higher than all the trees of the field. Its branches multiplied, and its boughs grew long as it spread them out because of the abundant waters.", "asv": "Therefore its stature was exalted above all the trees of the field; and its boughs were multiplied, and its branches became long by reason of many waters, when it shot them forth.", "ylt": "Therefore higher hath been his stature than all trees of the field, And multiplied are his boughs, and long are his branches, Because of many waters in his shooting forth,", "dra": "Therefore was his height exalted above all the trees of the country and his branches were multiplied, and his boughs were elevated because of many waters.", "bbe": "In this way it became taller than all the trees of the field; and its branches were increased and its arms became long because of the great waters.", "geneva": "Therefore his height was exalted aboue all the trees of the fielde, and his boughes were multiplied, and his branches were long, because of the multitude of the waters, which the deepe sent out.", "wycliffe": "Therfor his hiynesse was enhaunsid ouer alle trees of the cuntrei, and hise trees weren multiplied, and hise braunchis weren reisid, for many watris.", "rotherham": "For this cause higher, was his stature than any of the trees of the field,-And multiplied were his boughs And lengthened were his branches, By reason of the mighty waters when he shot forth shoots.", "darby": "Therefore his height was exalted above all the trees of the field, and his boughs were multiplied, and his branches became long, because of great waters, when he shot forth.", "twenty": "", "jps": "Therefore its stature was exalted above all the trees of the field; and its boughs were multiplied, and its branches became long, because of the multitude of waters, when it shot them forth.", "acv": "Therefore its stature was exalted above all the trees of the field, and its boughs were multiplied, and its branches became long because of many waters, when it shot them forth.", "anderson": "", "haweis": "", "noyes": "Therefore his height was exalted Above all the trees of the field. And his boughs were multiplied, and his branches became long, Because of the abundance of water when he shot forth.", "webster": "Therefore his hight was exalted above all the trees of the field, and his boughs were multiplied, and his branches became long because of the multitude of waters, when he shot forth.", "vulgate": "propterea elevata est altitudo eius super omnia ligna regionis et multiplicata sunt arbusta eius et elevati sunt rami eius prae aquis multis;", "brenton": "Therefore was his stature exalted above all the trees of the field, and his branches spread far by the help of much water."}}, {"v": 6, "ref": "31:6", "o": "בִּ/סְעַפֹּתָ֤י/ו קִֽנְנוּ֙ כָּל ע֣וֹף הַ/שָּׁמַ֔יִם וְ/תַ֤חַת פֹּֽארֹתָי/ו֙ יָֽלְד֔וּ כֹּ֖ל חַיַּ֣ת הַ/שָּׂדֶ֑ה וּ/בְ/צִלּ/וֹ֙ יֵֽשְׁב֔וּ כֹּ֖ל גּוֹיִ֥ם רַבִּֽים", "en": {"kjv": "All the fowls of heaven made their nests in his boughs, and under his branches did all the beasts of the field bring forth their young, and under his shadow dwelt all great nations.", "web": "All the birds of the sky made their nests in its boughs; and under its branches all the animals of the field gave birth to their young; and all great nations lived under its shadow.", "bsb": "All the birds of the air nested in its branches, and all the beasts of the field gave birth beneath its boughs; all the great nations lived in its shade.", "asv": "All the birds of the heavens made their nests in its boughs; and under its branches did all the beasts of the field bring forth their young; and under its shadow dwelt all great nations.", "ylt": "In his boughs made a nest hath every fowl of the heavens, And under his branches brought forth hath every beast of the field, And in his shade dwell do all great nations.", "dra": "And when he had spread forth his shadow, all the fowls of the air made their nests in his boughs, and all the beasts of the forest brought forth their young under his branches, and the assembly of many nations dwelt under his shadow.", "bbe": "In its branches all the birds of heaven came to rest, and under its arms all the beasts of the field gave birth to their young, and great nations were living in its shade.", "geneva": "All the foules of the heauen made their nestes in his boughes, and vnder his branches did all the beastes of the fielde bring foorth their yong, and vnder his shadowe dwelt all mightie nations.", "wycliffe": "And whanne he hadde stretchid forth his schadewe, alle the volatils of the eir maden nestis in hise braunchis; and alle the beestis of forestis gendriden vndur hise boowis, and the cumpeny of ful many folkis dwellide vndur the schadewynge place of hym.", "rotherham": "Among his branches, all the birds of the heavens, made their nests, And under his boughs, all the wild beasts of the field, brought forth,— And, in his shade, dwelt all the mighty nations.", "darby": "All the fowl of the heavens made their nests in his boughs, and under his branches did all the beasts of the field bring forth their young, and under his shadow dwelt all the great nations.", "twenty": "", "jps": "All the fowls of heaven made their nests in its boughs, and all the beasts of the field did bring forth their young under its branches, and under its shadow dwelt all great nations.", "acv": "All the birds of the heavens made their nests in its boughs, and under its branches all the beasts of the field brought forth their young, and under its shadow dwelt all great nations.", "anderson": "", "haweis": "", "noyes": "In his boughs all the birds of heaven made their nests, And under his branches all the beasts of the field brought forth their young; And under his shadow dwelt all the great nations.", "webster": "All the fowls of heaven made their nests in his boughs, and under his branches did all the beasts of the field bring forth their young, and under his shade dwelt all great nations.", "vulgate": "cumque extendisset umbram suam in ramis eius fecerunt nidos omnia volatilia caeli et sub frondibus eius genuerunt omnes bestiae saltuum et sub umbraculo illius habitabat coetus gentium plurimarum;", "brenton": "All the birds of the sky made their nests in his boughs, and under his branches all the wild beasts of the field bred; the whole multitude of nations dwelt under his shadow."}}, {"v": 7, "ref": "31:7", "o": "וַ/יְּיִ֣ף בְּ/גָדְל֔/וֹ בְּ/אֹ֖רֶךְ דָּֽלִיּוֹתָ֑י/ו כִּֽי הָיָ֥ה שָׁרְשׁ֖/וֹ אֶל מַ֥יִם רַבִּֽים", "en": {"kjv": "Thus was he fair in his greatness, in the length of his branches: for his root was by great waters.", "web": "Thus was it beautiful in its greatness, in the length of its branches; for its root was by many waters.", "bsb": "It was beautiful in its greatness, in the length of its limbs, for its roots extended to abundant waters.", "asv": "Thus was it fair in its greatness, in the length of its branches; for its root was by many waters.", "ylt": "And he is fair in his greatness, In the length of his thin shoots, For his root hath been by great waters.", "dra": "And he was most beautiful for his greatness, and for the spreading of his branches: for his root was near great waters.", "bbe": "So it was beautiful, being so tall and its branches so long, for its root was by great waters.", "geneva": "Thus was he faire in his greatnesse, and in the length of his branches: for his roote was neere great waters.", "wycliffe": "And he was ful fair in his greetnesse, and in alargyng of hise trees; for the roote of hym was bisidis many watris.", "rotherham": "Thus became he beautiful in his greatness, In the length of his waving branches, Because his root had gone towards mighty waters.", "darby": "Thus was he fair in his greatness, in the length of his branches: because his root was by great waters.", "twenty": "", "jps": "Thus was it fair in its greatness, in the length of its branches; for its root was by many waters.", "acv": "Thus it was beautiful in its greatness, in the length of its branches, for its root was by many waters.", "anderson": "", "haweis": "", "noyes": "Thus was he beautiful in his greatness, in the length of his branches; For his root was by many waters.", "webster": "Thus was he fair in his greatness, in the length of his branches: for his root was by great waters.", "vulgate": "eratque pulcherrimus in magnitudine sua et in dilatatione arbustorum suorum erat enim radix illius iuxta aquas multas;", "brenton": "And he was fair in his height by reason of the multitude of his branches: for his roots were amidst much water."}}, {"v": 8, "ref": "31:8", "o": "אֲרָזִ֣ים לֹֽא עֲמָמֻ/הוּ֮ בְּ/גַן אֱלֹהִים֒ בְּרוֹשִׁ֗ים לֹ֤א דָמוּ֙ אֶל סְעַפֹּתָ֔י/ו וְ/עַרְמֹנִ֥ים לֹֽא הָי֖וּ כְּ/פֹֽארֹתָ֑י/ו כָּל עֵץ֙ בְּ/גַן אֱלֹהִ֔ים לֹא דָמָ֥ה אֵלָ֖י/ו בְּ/יָפְיֽ/וֹ", "en": {"kjv": "The cedars in the garden of God could not hide him: the fir trees were not like his boughs, and the chesnut trees were not like his branches; nor any tree in the garden of God was like unto him in his beauty.", "web": "The cedars in the garden of God could not hide it; the fir trees were not like its boughs, and the plane trees were not as its branches; nor was any tree in the garden of God like it in its beauty.", "bsb": "The cedars in the garden of God could not rival it; the cypresses could not compare with its branches, nor the plane trees match its boughs. No tree in the garden of God could compare with its beauty.", "asv": "The cedars in the garden of God could not hide it; the fir-trees were not like its boughs, and the plane-trees were not as its branches; nor was any tree in the garden of God like unto it in its beauty.", "ylt": "Cedars have not hid him in the garden of God, Firs have not been like unto his boughs, And chesnut-trees have not been as his branches, No tree in the garden of God hath been like unto him in his beauty,", "dra": "The cedars in the paradise of God were not higher than he, the fir trees did not equal his top, neither were the plane trees to be compared with him for branches: no tree in the paradise of God was like him in his beauty.", "bbe": "No cedars were equal to it in the garden of God; the fir-trees were not like its branches, and plane-trees were as nothing in comparison with its arms; no tree in the garden of God was so beautiful.", "geneva": "The cedars in the garden of God coulde not hide him: no firre tree was like his branches, and the chessenut trees were not like his boughes: all the trees in the garden of God were not like vnto him in his beautie.", "wycliffe": "Cedris in the paradijs of God weren not hiyere than he; fir trees atteyneden not euenli to the hiynesse of hym, and plane trees weren not euene with the boowis of hym. Ech tree of paradijs of God was not maad lic hym and his fairnesse.", "rotherham": "Cedars hid him not. in the garden of God, Fir-trees were not like unto his boughs, Nor plane-trees, like his branches,—no, tree in the garden of God, was like unto him in his beauty.", "darby": "The cedars in the garden ofGod could not hide him; the cypresses were not like his boughs, and the plane-trees were not as his branches: no tree in the garden ofGod was like unto him in his beauty.", "twenty": "", "jps": "The cedars in the garden of G-d could not hide it; the cypress-trees were not like its boughs, and the plane-trees were not as its branches; nor was any tree in the garden of G-d like unto it in its beauty.", "acv": "The cedars in the garden of God could not dim it. The fir trees were not like its boughs, and the plane trees were not as its branches, nor was any tree in the garden of God like it in its beauty.", "anderson": "", "haweis": "", "noyes": "The cedars in the garden of God could not hide him; The cypress-trees were not like his boughs, And the plane-trees were not like his branches. Not any tree in the garden of God Was like to him in his beauty.", "webster": "The cedars in the garden of God could not hide him: the fir-trees were not like his boughs, and the chesnut-trees were not like his branches; not any tree in the garden of God was like to him in his beauty.", "vulgate": "cedri non fuerunt altiores illo in paradiso Dei abietes non adaequaverunt summitatem eius et platani non fuerunt aequae frondibus illius omne lignum paradisi Dei non est adsimilatum illi et pulchritudini eius;", "brenton": "And such cypresses as this were in the paradise of God; and there were no pines like his shoots, and there were no firs like his branches: no tree in the paradise of God was like him in his beauty,"}}, {"v": 9, "ref": "31:9", "o": "יָפֶ֣ה עֲשִׂיתִ֔י/ו בְּ/רֹ֖ב דָּֽלִיּוֹתָ֑י/ו וַ/יְקַנְאֻ֨/הוּ֙ כָּל עֲצֵי עֵ֔דֶן אֲשֶׁ֖ר בְּ/גַ֥ן הָ/אֱלֹהִֽים", "en": {"kjv": "I have made him fair by the multitude of his branches: so that all the trees of Eden, that were in the garden of God, envied him.", "web": "I made it beautiful by the multitude of its branches, so that all the trees of Eden, that were in the garden of God, envied it.", "bsb": "I made it beautiful with its many branches, the envy of all the trees of Eden, which were in the garden of God.’", "asv": "I made it fair by the multitude of its branches, so that all the trees of Eden, that were in the garden of God, envied it.", "ylt": "Fair I have made him in the multitude of his thin shoots, And envy him do all trees of Eden that are in the garden of God.", "dra": "For I made him beautiful and thick set with many branches: and all the trees of pleasure, that were in the paradise of God, envied him.", "bbe": "I made it beautiful with its mass of branches: so that all the trees in the garden of God were full of envy of it.", "geneva": "I made him faire by the multitude of his branches: so that all the trees of Eden, that were in the garden of God, enuied him.", "wycliffe": "For Y made hym fair, and with many and thicke boowis; and alle the trees of lust, that weren in the paradijs of God, hadden enuye to hym.", "rotherham": "Beautiful, I made him in the abundance of his waving branches,- Therefore was he envied by all the trees of Eden, which were in the garden of God.", "darby": "I had made him fair by the multitude of his branches; and all the trees of Eden, that were in the garden ofGod, envied him.", "twenty": "", "jps": "I made it fair by the multitude of its branches; so that all the trees of Eden, that were in the garden of G-d, envied it.", "acv": "I made it beautiful by the multitude of its branches, so that all the trees of Eden, that were in the garden of God, envied it.", "anderson": "", "haweis": "", "noyes": "I made him beautiful in the multitude of his branches, So that all the trees of Eden, which were in the garden of God, envied him.", "webster": "I have made him fair by the multitude of his branches: so that all the trees of Eden, that [were] in the garden of God, envied him.", "vulgate": "quoniam speciosum feci eum et multis condensisque frondibus et aemulata sunt eum omnia ligna voluptatis quae erant in paradiso Dei;", "brenton": "because of the multitude of his branches: and the trees of God's paradise of delight envied him."}}, {"v": 10, "ref": "31:10", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֕עַן אֲשֶׁ֥ר גָּבַ֖הְתָּ בְּ/קוֹמָ֑ה וַ/יִּתֵּ֤ן צַמַּרְתּ/וֹ֙ אֶל בֵּ֣ין עֲבוֹתִ֔ים וְ/רָ֥ם לְבָב֖/וֹ בְּ/גָבְהֽ/וֹ", "en": {"kjv": "Therefore thus saith the Lord God; Because thou hast lifted up thyself in height, and he hath shot up his top among the thick boughs, and his heart is lifted up in his height;", "web": "Therefore thus said the Lord Yahweh: Because you are exalted in stature, and he has set his top among the thick boughs, and his heart is lifted up in his height;", "bsb": "Therefore this is what the Lord GOD says: ‘Since it became great in height and set its top among the clouds, and it grew proud on account of its height,", "asv": "Therefore thus said the Lord Jehovah: Because thou art exalted in stature, and he hath set his top among the thick boughs, and his heart is lifted up in his height;", "ylt": "Therefore, thus said the Lord Jehovah: Because that thou hast been high in stature, And he yieldeth his foliage between thickets, And high is his heart in his haughtiness,", "dra": "Therefore thus saith the Lord God: Because he was exalted in height, and shot up his top green and thick, and his heart was lifted up in his height:", "bbe": "For this cause the Lord has said: Because he is tall, and has put his top among the clouds, and his heart is full of pride because he is so high,", "geneva": "Therefore thus sayeth the Lord God, Because he is lift vp on high, and hath shot vp his toppe among the thicke boughes, and his heart is lift vp in his height,", "wycliffe": "Therfor the Lord God seith these thingis, For that that he was reisid in hiynesse, and he yaf his hyynesse greene and thicke, and his herte was reisid in his hiynesse;", "rotherham": "Therefore Thus, saith My Lord Yahweh, Because thou hast become lofty in stature, And he hath stretched his top among the clouds, And his heart is exalted in his loftiness.", "darby": "Therefore thus saith the Lord Jehovah: Because thou hast lifted up thyself in stature, ...and he hath set his top amidst the thick boughs, and his heart is lifted up in his height,", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Because thou art exalted in stature, and he hath set his top among the thick boughs, and his heart is lifted up in his height;", "acv": "Therefore thus said the lord Jehovah: Because thou are exalted in stature, and he has set his top among the thick boughs, and his heart is lifted up in his height,", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Because he lifted himself up in stature, And shot up his top among the thick boughs, And his heart was lifted up on account of his height,", "webster": "Therefore thus saith the Lord GOD; Because thou hast lifted up thyself in hight, and he hath shot up his top among the thick boughs, and his heart is lifted up in his hight;", "vulgate": "propterea haec dicit Dominus Deus pro eo quod sublimatus est in altitudine et dedit summitatem suam virentem atque condensam et elevatum est cor eius in altitudine sua;", "brenton": "Therefore thus saith the Lord; Because thou art grown great, and hast set thy top in the midst of the clouds, and I saw when he was exalted;"}}, {"v": 11, "ref": "31:11", "o": "וְ/אֶ֨תְּנֵ֔/הוּ בְּ/יַ֖ד אֵ֣יל גּוֹיִ֑ם עָשׂ֤וֹ יַֽעֲשֶׂה֙ ל֔/וֹ כְּ/רִשְׁע֖/וֹ גֵּרַשְׁתִּֽ/הוּ", "en": {"kjv": "I have therefore delivered him into the hand of the mighty one of the heathen; he shall surely deal with him: I have driven him out for his wickedness.", "web": "I will even deliver him into the hand of the mighty one of the nations; he shall surely deal with him; I have driven him out for his wickedness.", "bsb": "I delivered it into the hand of the ruler of the nations, for him to deal with it according to its wickedness. I have banished it.", "asv": "I will even deliver him into the hand of the mighty one of the nations; he shall surely deal with him; I have driven him out for his wickedness.", "ylt": "I give him into the hand of a god of nations, He dealeth sorely with him, In his wickedness I have cast him out.", "dra": "I have delivered him into the hands of the mighty one of the nations, he shall deal with him: I have cast him out according to his wickedness.", "bbe": "I have given him up into the hands of a strong one of the nations; he will certainly give him the reward of his sin, driving him out.", "geneva": "I haue therefore deliuered him into the handes of the mightiest among the heathen: he shall handle him, for I haue cast him away for his wickednesse.", "wycliffe": "now Y haue youe hym in to the hondis of the strongeste man of hethene men. And he doynge schal do to that Assur; aftir the vnfeithfulnesse of hym Y castide hym out.", "rotherham": "Let me then deliver him into the hand of the chief of the nations, He shall effectually deal with him! According to his lawlessness, have I driven him out:", "darby": "I have given him into the hand of the mighty one of the nations; he shall surely deal with him: I have driven him out for his wickedness.", "twenty": "", "jps": "I do even deliver him into the hand of the mighty one of the nations; he shall surely deal with him; I do drive him out according to his wickedness.", "acv": "I will even deliver him into the hand of the mighty one of the nations. He shall surely deal with him; I have driven him out for his wickedness.", "anderson": "", "haweis": "", "noyes": "Therefore I delivered him into the hand of the mighty one of the nations, To deal hardly with him; I drave him out for his wickedness;", "webster": "I have therefore delivered him into the hand of the mighty one of the heathen; he shall surely deal with him: I have driven him out for his wickedness.", "vulgate": "tradidi eum in manu fortissimi gentium faciens faciet ei iuxta impietatem eius eieci eum;", "brenton": "therefore I delivered him into the hands of the prince of the nations, and he wrought his destruction."}}, {"v": 12, "ref": "31:12", "o": "וַ/יִּכְרְתֻ֧/הוּ זָרִ֛ים עָרִיצֵ֥י גוֹיִ֖ם וַֽ/יִּטְּשֻׁ֑/הוּ אֶל הֶ֠/הָרִים וּ/בְ/כָל גֵּ֨אָי֜וֹת נָפְל֣וּ דָלִיּוֹתָ֗י/ו וַ/תִּשָּׁבַ֤רְנָה פֹֽארֹתָי/ו֙ בְּ/כֹל֙ אֲפִיקֵ֣י הָ/אָ֔רֶץ וַ/יֵּרְד֧וּ מִ/צִּלּ֛/וֹ כָּל עַמֵּ֥י הָ/אָ֖רֶץ וַֽ/יִּטְּשֻֽׁ/הוּ", "en": {"kjv": "And strangers, the terrible of the nations, have cut him off, and have left him: upon the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the rivers of the land; and all the people of the earth are gone down from his shadow, and have left him.", "web": "Strangers, the terrible of the nations, have cut him off, and have left him: on the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the watercourses of the land; and all the peoples of the earth are gone down from his shadow, and have left him.", "bsb": "Foreigners, the most ruthless of the nations, cut it down and left it. Its branches have fallen on the mountains and in every valley; its boughs lay broken in all the earth’s ravines. And all the peoples of the earth left its shade and abandoned it.", "asv": "And strangers, the terrible of the nations, have cut him off, and have left him: upon the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the watercourses of the land; and all the peoples of the earth are gone down from his shadow, and have left him.", "ylt": "And cut him off do strangers, The terrible of nations, and they leave him, On the mountains and in all valleys have his thin shoots fallen, And broken are his boughs at all streams of the land, And go down from his shade do all peoples of the land, and they leave him.", "dra": "And strangers, and the most cruel of the nations shall cut him down, and cast him away upon the mountains, and his boughs shall fall in every valley, and his branches shall be broken on every rock of the country: and all the people of the earth shall depart from his shadow, and leave him.", "bbe": "And men from strange lands, who are to be feared among the nations, after cutting him off, have let him be: on the mountains and in all the valleys his branches have come down; his arms are broken by all the waterways of the land; all the peoples of the earth have gone from his shade, and have let him be.", "geneva": "And the strangers haue destroyed him, euen the terrible nations, and they haue left him vpon the mountaines, and in all the valleis his branches are fallen, and his boughes are broken by all the riuers of the land: and all the people of the earth are departed from his shadowe, and haue forsaken him.", "wycliffe": "And aliens, and the moost cruel men of naciouns, schulen kitte hym doun, and schulen caste hym forth on hillis. And hise braunchis schulen falle doun in alle grete valeis, and hise trees schulen be brokun in alle roochis of stoon of erthe. And alle the puplis of erthe schulen go awei fro his schadewing place, and schulen forsake hym.", "rotherham": "Therefore have foreigners the terrible of the nations cut him down. And abandoned him,— Upon the mountains and in all valleys, have fallen his waving branches And broken have been his boughs in all the river-beds of the land, And all the peoples of the earth have come down out of his shade. And abandoned him:", "darby": "And strangers, the terrible of the nations, have cut him off and have left him; upon the mountains and in all the valleys his branches are fallen, and his boughs are broken in all the watercourses of the land; and all the peoples of the earth are gone down from his shadow, and have left him.", "twenty": "", "jps": "And strangers, the terrible of the nations, do cut him off, and cast him down; upon the mountains and in all the valleys his branches are fallen, and his boughs lie broken in all the channels of the land; and all the peoples of the earth do go down from his shadow, and do leave him.", "acv": "And strangers, the terrible of the nations, have cut him off, and have left him. Upon the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the watercourses of the land. And all the peoples of the earth have gone down from his shadow, and have left him.", "anderson": "", "haweis": "", "noyes": "And strangers, the terrible of the nations, cut him off and cast him away. Upon the mountains and in all the valleys his branches fell; And his boughs were broken in all the valleys of the land. And all the nations of the earth withdrew from his shadow and left him;", "webster": "And strangers, the terrible of the nations, have cut him off, and have left him: upon the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the rivers of the land; and all the people of the earth have gone down from his shade, and have left him.", "vulgate": "et succident illum alieni et crudelissimi nationum et proicient eum super montes et in cunctis convallibus corruent rami eius et confringentur arbusta eius in universis rupibus terrae et recedent de umbraculo eius omnes populi terrae et relinquent eum;", "brenton": "And ravaging strangers from the nations have destroyed him, and have cast him down upon the mountains: his branches fell in all the valleys, and his boughs were broken in every field of the land; and all the people of the nations are gone down from their shelter, and have laid him low."}}, {"v": 13, "ref": "31:13", "o": "עַל מַפַּלְתּ֥/וֹ יִשְׁכְּנ֖וּ כָּל ע֣וֹף הַ/שָּׁמָ֑יִם וְ/אֶל פֹּארֹתָ֣י/ו הָי֔וּ כֹּ֖ל חַיַּ֥ת הַ/שָּׂדֶֽה", "en": {"kjv": "Upon his ruin shall all the fowls of the heaven remain, and all the beasts of the field shall be upon his branches:", "web": "On his ruin all the birds of the sky shall dwell, and all the animals of the field shall be on his branches;", "bsb": "All the birds of the air nested on its fallen trunk, and all the beasts of the field lived among its boughs.", "asv": "Upon his ruin all the birds of the heavens shall dwell, and all the beasts of the field shall be upon his branches;", "ylt": "On his ruin dwell do all fowls of the heavens, And on his boughs have been all the beasts of the field,", "dra": "All the fowls of the air dwelt upon his ruins, and all the beasts of the field were among his branches.", "bbe": "All the birds of heaven have come to rest on his broken stem where it is stretched on the earth, and all the beasts of the field will be on his branches:", "geneva": "Vpon his ruine shall all the foules of the heauen remaine, and all the beastes of the fielde shall be vpon his branches,", "wycliffe": "Alle volatils of the eir dwelliden in the fallyng of hym, and alle beestis of the cuntrei weren in the braunchis of hym.", "rotherham": "Upon his trunk, shall settle down all the birds of the heavens,- And among his boughs, are to be found all the wild beasts of the field:—", "darby": "Upon his fallen [trunk] do all the fowl of the heavens dwell, and all the beasts of the field are upon his branches:", "twenty": "", "jps": "Upon his carcass all the fowls of the heaven do dwell, and upon his branches are all the beasts of the field;", "acv": "All the birds of the heavens shall dwell upon his ruin, and all the beasts of the field shall be upon his branches,", "anderson": "", "haweis": "", "noyes": "Upon his ruin dwelt all the birds of the heavens, And upon his branches were all the beasts of the forest.", "webster": "Upon his ruin shall all the fowls of the heaven remain, and all the beasts of the field shall be upon his branches:", "vulgate": "in ruina eius habitaverunt omnia volatilia caeli et in ramis eius fuerunt universae bestiae regionis;", "brenton": "All the birds of the sky have settled on his fallen trunk, and all the wild beasts of the field came upon his boughs:"}}, {"v": 14, "ref": "31:14", "o": "לְמַ֡עַן אֲשֶׁר֩ לֹא יִגְבְּה֨וּ בְ/קוֹמָתָ֜/ם כָּל עֲצֵי מַ֗יִם וְ/לֹֽא יִתְּנ֤וּ אֶת צַמַּרְתָּ/ם֙ אֶל בֵּ֣ין עֲבֹתִ֔ים וְ/לֹֽא יַעַמְד֧וּ אֵלֵי/הֶ֛ם בְּ/גָבְהָ֖/ם כָּל שֹׁ֣תֵי מָ֑יִם כִּֽי כֻלָּ/ם֩ נִתְּנ֨וּ לַ/מָּ֜וֶת אֶל אֶ֣רֶץ תַּחְתִּ֗ית בְּ/ת֛וֹךְ בְּנֵ֥י אָדָ֖ם אֶל י֥וֹרְדֵי בֽוֹר", "en": {"kjv": "To the end that none of all the trees by the waters exalt themselves for their height, neither shoot up their top among the thick boughs, neither their trees stand up in their height, all that drink water: for they are all delivered unto death, to the nether parts of the earth, in the midst of the children of men, with them that go down to the pit.", "web": "to the end that none of all the trees by the waters exalt themselves in their stature, neither set their top among the thick boughs, nor that their mighty ones stand up on their height, even all who drink water: for they are all delivered to death, to the lower parts of the earth, in the midst of the children of men, with those who go down to the pit.", "bsb": "This happened so that no other trees by the waters would become great in height and set their tops among the clouds, and no other well-watered trees would reach them in height. For they have all been consigned to death, to the depths of the earth, among the mortals who descend to the Pit.’", "asv": "to the end that none of all the trees by the waters exalt themselves in their stature, neither set their top among the thick boughs, nor that their mighty ones stand up in their height, even all that drink water: for they are all delivered unto death, to the nether parts of the earth, in the midst of the children of men, with them that go down to the pit.", "ylt": "In order that none of the trees of the waters May become haughty because of their stature, Nor give their foliage between thickets, Nor any drinking waters stand up unto them in their haughtiness, For all of them are given up to death, Unto the earth--the lower part, In the midst of the sons of men, Unto those going down to the pit.", "dra": "For which cause none of the trees by the waters shall exalt themselves for their height: nor shoot up their tops among the thick branches and leaves, neither shall any of them that are watered stand up in their height: for they are all delivered unto death to the lowest parts of the earth, in the midst of the children of men, with them that go down into the pit.", "bbe": "In order that no trees by the waters may be lifted up in their growth, putting their tops among the clouds; and that no trees which are watered may take their place on high: for they are all given up to death, to the lowest parts of the earth among the children of men, with those who go down to the underworld.", "geneva": "So that none of all the trees by the waters shalbe exalted by their height, neither shall shoote vp their toppe among the thicke boughes, neither shall their leaues stand vp in their height, which drinke so much water: for they are all deliuered vnto death in the nether partes of the earth in the middes of the children of men among them that goe downe to the pit.", "wycliffe": "Wherfor alle the trees of watris schulen not be reisid in hir hiynesse, nether schulen sette hir hiynesse among places ful of woode, and ful of boowis, and alle trees that ben moistid of watris schulen not stonde in the hiynesse of tho. For alle thei ben youun in to deth, to the ferthest lond in the myddis of the sones of men, to hem that goon doun in to the lake.", "rotherham": "To the end that none of the trees of the waters— May exalt themselves in their stature or stretch their top among the clouds, Nor their mighty ones take their stand in their height- any that drink of the waters,— Because they all, are delivered to death Unto the earth below. In the midst of the sons of Adam. Amongst them who descend into the pit.", "darby": "to the end that none of all the trees by the waters exalt themselves in their stature, nor set their top amidst the thick boughs, and that none of them that drink water stand up in his height by himself; for they are all given over unto death in the lower parts of the earth, in the midst of the children of men, with them that go down to the pit.", "twenty": "", "jps": "to the end that none of all the trees by the waters exalt themselves in their stature, neither set their top among the thick boughs, nor that their mighty ones stand up in their height, even all that drink water; for they are all delivered unto death, to the nether parts of the earth, in the midst of the children of men, with them that go down to the pit.", "acv": "to the end that none of all the trees by the waters exalt themselves in their stature, neither set their top among the thick boughs, nor that their mighty ones stand up on their height, even all that drink water. For they are all delivered to death, to the nether parts of the earth, in the midst of the sons of men, with those who go down to the pit.", "anderson": "", "haweis": "", "noyes": "To the end that none of all the trees by the waters Might exalt themselves for their stature, Nor shoot up their top among the thick boughs, And that none of the trees that drink water should cleave to them on account of their height; For all of them are delivered to death, to the lower parts of the earth, In the midst of the sons of men, To them that have gone down to the pit.", "webster": "To the end that none of all the trees by the waters exalt themselves for their hight, neither shoot up their top among the thick boughs, neither their trees stand up in their hight, all that drink water: for they are all delivered to death, to the nether parts of the earth, in the midst of the children of men, with them that go down to the pit.", "vulgate": "quam ob rem non elevabuntur in altitudine sua omnia ligna aquarum neque ponent sublimitatem suam inter nemorosa atque frondosa nec stabunt in sublimitate eorum omnia quae inrigantur aquis quia omnes traditi sunt in mortem ad terram ultimam in medio filiorum hominum ad eos qui descendunt in lacum;", "brenton": "in order that none of the trees by the water should exalt themselves by reason of their size: whereas they set their top in the midst of the clouds, yet they continued not in their high state in their place, all that drank water, all were consigned to death, to the depth of the earth, in the midst of the children of men, with them that go down to the pit."}}, {"v": 15, "ref": "31:15", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה בְּ/י֨וֹם רִדְתּ֤/וֹ שְׁא֨וֹלָ/ה֙ הֶאֱבַ֜לְתִּי כִּסֵּ֤תִי עָלָי/ו֙ אֶת תְּה֔וֹם וָֽ/אֶמְנַע֙ נַהֲרוֹתֶ֔י/הָ וַ/יִּכָּלְא֖וּ מַ֣יִם רַבִּ֑ים וָ/אַקְדִּ֤ר עָלָי/ו֙ לְבָנ֔וֹן וְ/כָל עֲצֵ֥י הַ/שָּׂדֶ֖ה עָלָ֥י/ו עֻלְפֶּֽה", "en": {"kjv": "Thus saith the Lord God; In the day when he went down to the grave I caused a mourning: I covered the deep for him, and I restrained the floods thereof, and the great waters were stayed: and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "web": "Thus says the Lord Yahweh: In the day when he went down to Sheol I caused a mourning: I covered the deep for him, and I restrained its rivers; and the great waters were stayed; and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "bsb": "This is what the Lord GOD says: ‘On the day it was brought down to Sheol, I caused mourning. I covered the deep because of it; I held back its rivers; its abundant waters were restrained. I made Lebanon mourn for it, and all the trees of the field fainted because of it.", "asv": "Thus saith the Lord Jehovah: In the day when he went down to Sheol I caused a mourning: I covered the deep for him, and I restrained the rivers thereof; and the great waters were stayed; and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "ylt": "Thus said the Lord Jehovah: In the day of his going down to sheol I have caused mourning, I have covered for him the deep, and diminish its flowings, And restrained are many waters, And I make Lebanon black for him, And all trees of the field have been covered for him.", "dra": "Thus saith the Lord God: In the day when he went down to hell, I brought in mourning, I covered him with the deep: and I withheld its rivers, and restrained the many waters: Libanus grieved for him, and all the trees of the field trembled.", "bbe": "This is what the Lord has said: The day when he goes down to the underworld, I will make the deep full of grief for him; I will keep back her streams and the great waters will be stopped: I will make Lebanon dark for him, and all the trees of the field will be feeble because of him.", "geneva": "Thus saith the Lord God, In the day when he went downe to hell, I caused them to mourne, and I couered the deepe for him, and I did restreine the floods thereof, and the great waters were stayed: I caused Lebanon to mourne for him, and all the trees of the fielde fainted.", "wycliffe": "The Lord God seith these thingis, In the dai whanne he yede doun to hellis, Y brouyte yn mourenyng; Y hilide hym with depthe of watris, and I forbede his flodis, and Y refreynede many watris. The Liban was sori on him, and alle the trees of the feeld", "rotherham": "Thus, saith My Lord Yahweh, In the day when he descended into hades, I caused a mourning. I covered over him the roaring deep, And restrained the currents thereof And stayed were the mighty waters, So caused I gloom over him unto Lebanon, And all the trees of the field for him were covered with a shroud.", "darby": "Thus saith the Lord Jehovah: In the day when he went down to Sheol, I caused a mourning: I covered the deep for him, and I restrained the floods thereof, and the great waters were stayed; and I made Lebanon black for him, and all the trees of the field fainted for him.", "twenty": "", "jps": "Thus saith the L-rd GOD: In the day when he went down to the nether-world I caused the deep to mourn and cover itself for him, and I restrained the rivers thereof, and the great waters were stayed; and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "acv": "Thus says the lord Jehovah: In the day when he went down to Sheol I caused a mourning. I covered the deep for him. And I restrained the rivers of it, and the great waters were stayed. And I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: In the day when he went down to the grave, I caused the deep to mourn, I covered it for him; I restrained on account of him the streams, and the great waters were kept back; And I caused Lebanon to mourn for him, And all the trees of the field fainted for him.", "webster": "Thus saith the Lord GOD; In the day when he went down to the grave I caused a mourning: I covered the deep for him, and I restrained its floods, and the great waters were stayed: and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.", "vulgate": "haec dicit Dominus Deus in die quando descendit ad inferos indixi luctum operui eum abysso et prohibui flumina eius et coercui aquas multas contristatus est super eum Libanus et omnia ligna agri concussa sunt;", "brenton": "Thus saith the Lord God; In the day wherein he went down to Hades, the deep mourned for him: and I stayed her floods, and restrained her abundance of water: and Libanus saddened for him, all the trees of the field fainted for him."}}, {"v": 16, "ref": "31:16", "o": "מִ/קּ֤וֹל מַפַּלְתּ/וֹ֙ הִרְעַ֣שְׁתִּי גוֹיִ֔ם בְּ/הוֹרִדִ֥/י אֹת֛/וֹ שְׁא֖וֹלָ/ה אֶת י֣וֹרְדֵי ב֑וֹר וַ/יִּנָּ֨חֲמ֜וּ בְּ/אֶ֤רֶץ תַּחְתִּית֙ כָּל עֲצֵי עֵ֔דֶן מִבְחַ֥ר וְ/טוֹב לְבָנ֖וֹן כָּל שֹׁ֥תֵי מָֽיִם", "en": {"kjv": "I made the nations to shake at the sound of his fall, when I cast him down to hell with them that descend into the pit: and all the trees of Eden, the choice and best of Lebanon, all that drink water, shall be comforted in the nether parts of the earth.", "web": "I made the nations to shake at the sound of his fall, when I cast him down to Sheol with those who descend into the pit; and all the trees of Eden, the choice and best of Lebanon, all that drink water, were comforted in the lower parts of the earth.", "bsb": "I made the nations quake at the sound of its downfall, when I cast it down to Sheol with those who descend to the Pit. Then all the trees of Eden, the choicest and best of Lebanon, all the well-watered trees, were consoled in the earth below.", "asv": "I made the nations to shake at the sound of his fall, when I cast him down to Sheol with them that descend into the pit; and all the trees of Eden, the choice and best of Lebanon, all that drink water, were comforted in the nether parts of the earth.", "ylt": "From the sound of his fall I have caused nations to shake, In My causing him to go down to sheol, With those going down to the pit, And comforted in the earth--the lower part, are all trees of Eden, The choice and the good of Lebanon, All drinking waters.", "dra": "I shook the nations with the sound of his fall, when I brought him down to hell with them that descend into the pit: and all the trees of pleasure, the choice and best in Libanus, all that were moistened with waters, were comforted in the lowest parts of the earth.", "bbe": "I will send shaking on the nations at the sound of his fall, when I send him down to the underworld with those who go down into the deep: and on earth they will be comforting themselves, all the trees of Eden, the best of Lebanon, even all the watered ones.", "geneva": "I made the nations to shake at the sound of his fall, when I cast him downe to hell with them that descend into the pit, and all the excellent trees of Eden, and the best of Lebanon: euen all that are nourished with waters, shall be comforted in the nether partes of the earth.", "wycliffe": "weren shakun of the soun of his falling. I mouide togidere hethene men, whanne Y ledde hym doun to helle, with hem that yeden doun in to the lake. And alle trees of likyng, noble trees, and ful cleere in the Liban, alle that weren moistid with watris, weren coumfortid in the loweste lond.", "rotherham": "At the sound of his fall, I made nations tremble, When I caused him to descend into hades, with them who descend into the pit,— Then were grieved in the earth below-All the trees of Eden, The choicest and best of Lebanon All who had drunk the waters.", "darby": "I made the nations to shake at the sound of his fall, when I cast him down to Sheol, with them that go down into the pit; and all the trees of Eden, the choice and best of Lebanon, all that drink water, were comforted in the lower parts of the earth.", "twenty": "", "jps": "I made the nations to shake at the sound of his fall, when I cast him down to the nether-world with them that descend into the pit; and all the trees of Eden, the choice and best of Lebanon, all that drink water, were comforted in the nether parts of the earth.", "acv": "I made the nations to shake at the sound of his fall when I cast him down to Sheol with those who descend into the pit. And all the trees of Eden, the choice and best of Lebanon, all that drink water, were comforted in the nether parts of the earth.", "anderson": "", "haweis": "", "noyes": "At the sound of his fall I made the nations to shake, When I cast him down to the grave, To them that have gone down to the pit; And all the trees of Eden, The choice and best of Lebanon, Even all that drink water, Were comforted in the lower parts of the earth.", "webster": "I made the nations to shake at the sound of his fall, when I cast him down to the grave with them that descend into the pit: and all the trees of Eden, the choice and best of Lebanon, all that drink water, shall be comforted in the nether parts of the earth.", "vulgate": "a sonitu ruinae eius commovi gentes cum deducerem eum ad infernum cum his qui descendebant in lacum et consolata sunt in terra infima omnia ligna voluptatis egregia atque praeclara in Libano universa quae inrigabantur aquis;", "brenton": "At the sound of his fall the nations quaked, when I brought him down to Hades with them that go down to the pit: and all the trees of Delight comforted him in the heart, and the choice of plants of Libanus, all that drink water."}}, {"v": 17, "ref": "31:17", "o": "גַּם הֵ֗ם אִתּ֛/וֹ יָרְד֥וּ שְׁא֖וֹלָ/ה אֶל חַלְלֵי חָ֑רֶב וּ/זְרֹע֛/וֹ יָשְׁב֥וּ בְ/צִלּ֖/וֹ בְּ/ת֥וֹךְ גּוֹיִֽם", "en": {"kjv": "They also went down into hell with him unto them that be slain with the sword; and they that were his arm, that dwelt under his shadow in the midst of the heathen.", "web": "They also went down into Sheol with him to those who are slain by the sword; yes, those who were his arm, who lived under his shadow in the midst of the nations.", "bsb": "They too descended with it to Sheol, to those slain by the sword. As its allies they had lived in its shade among the nations.", "asv": "They also went down into Sheol with him unto them that are slain by the sword; yea, they that were his arm, that dwelt under his shadow in the midst of the nations.", "ylt": "Also they with him have gone down to sheol, Unto the pierced of the sword, And--his arm--they dwelt in his shade in the midst of nations.", "dra": "For they also shall go down with him to hell to them that are slain by the sword; and the arm of every one shall sit down under his shadow in the midst of the nations.", "bbe": "And they will go down with him to the underworld, to those who have been put to the sword; even those who were his helpers, living under his shade among the nations", "geneva": "They also went downe to hell with him vnto them that be slaine with the sworde, and his arme, and they that dwelt vnder his shadowe in the middes of the heathen.", "wycliffe": "For whi also thei schulen go doun with hym to helle, to slayn men with swerd; and the arm of ech man schal sitte vndur the schadewyng place of hym, in the myddis of naciouns.", "rotherham": "Even they, with him descended into hades. Among them who were thrust through with the sword,- Even his seed who dwelt in his shade in the midst of the nations.", "darby": "They also went down into Sheol with him unto them that were slain with the sword, and [that were] his arm, that dwelt under his shadow in the midst of the nations.", "twenty": "", "jps": "They also went down into the nether-world with him unto them that are slain by the sword; yea, they that were in his arm, that dwelt under his shadow in the midst of the nations.", "acv": "They also went down into Sheol with him to those who are slain by the sword, yea, those who were his arm, that dwelt under his shadow in the midst of the nations.", "anderson": "", "haweis": "", "noyes": "They also went down into the grave with him, To them that have been slain with the sword; They also that were his arm, That dwelt under his shadow among the nations.", "webster": "They also went down into the grave with him to [them that are] slain with the sword; and [they that were] his arm, [that] dwelt under his shade in the midst of the heathen.", "vulgate": "nam et ipsi cum ea descendent ad infernum ad interfectos gladio et brachium uniuscuiusque sedebit sub umbraculo eius in medio nationum;", "brenton": "For they went down to hell with him among the slain with the sword; and his seed, even they that dwelt under his shadow, perished in the midst of their life."}}, {"v": 18, "ref": "31:18", "o": "אֶל מִ֨י דָמִ֥יתָ כָּ֛כָה בְּ/כָב֥וֹד וּ/בְ/גֹ֖דֶל בַּ/עֲצֵי עֵ֑דֶן וְ/הוּרַדְתָּ֨ אֶת עֲצֵי עֵ֜דֶן אֶל אֶ֣רֶץ תַּחְתִּ֗ית בְּ/ת֨וֹךְ עֲרֵלִ֤ים תִּשְׁכַּב֙ אֶת חַלְלֵי חֶ֔רֶב ה֤וּא פַרְעֹה֙ וְ/כָל הֲמוֹנֹ֔/ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "To whom art thou thus like in glory and in greatness among the trees of Eden? yet shalt thou be brought down with the trees of Eden unto the nether parts of the earth: thou shalt lie in the midst of the uncircumcised with them that be slain by the sword. This is Pharaoh and all his multitude, saith the Lord God.", "web": "To whom are you thus like in glory and in greatness among the trees of Eden? yet you will be brought down with the trees of Eden to the lower parts of the earth: you shall lie in the midst of the uncircumcised, with those who are slain by the sword. This is Pharaoh and all his multitude, says the Lord Yahweh.", "bsb": "Who then is like you in glory and greatness among the trees of Eden? You also will be brought down to the depths of the earth to be with the trees of Eden. You will lie among the uncircumcised, with those slain by the sword. This is Pharaoh and all his multitude, declares the Lord GOD.’”", "asv": "To whom art thou thus like in glory and in greatness among the trees of Eden? yet shalt thou be brought down with the trees of Eden unto the nether parts of the earth: thou shalt lie in the midst of the uncircumcised, with them that are slain by the sword. This is Pharaoh and all his multitude, saith the Lord Jehovah.", "ylt": "Unto whom hast thou been thus like, In honour and in greatness among the trees of Eden, And thou hast been brought down with the trees of Eden, Unto the earth--the lower part, In the midst of the uncircumcised thou liest, With the pierced of the sword? It is Pharaoh, and all his multitude, An affirmation of the Lord Jehovah!'", "dra": "To whom art thou like, O thou that art famous and lofty among the trees of pleasure? Behold, thou art brought down with the trees of pleasure to the lowest parts of the earth: thou shalt sleep in the midst of the uncircumcised, with them that are slain by the sword: this is Pharao, and all his multitude, saith the Lord God.", "bbe": "Whom then are you like? for you will be sent down with the trees of Eden into the lowest parts of the earth: there you will be stretched out among those without circumcision, with those who were put to the sword. This is Pharaoh and all his people, says the Lord.", "geneva": "To whom art thou thus like in glorie and in greatnesse among the trees of Eden? yet thou shalt be cast downe with the trees of Eden vnto the nether partes of the earth: thou shalt sleepe in the middes of the vncircumcised, with them that be slaine by the sworde: this is Pharaoh and all his multitude, sayth the Lord God.", "wycliffe": "To whom art thou licned, thou noble and hiy among the trees of likyng? Lo! thou art led doun with the trees of likyng to the fertheste lond. In the myddis of vncircumcidid men thou schalt slepe, with hem that ben slayn bi swerd. Thilke is Farao, and al the multitude of hym, seith the Lord God.", "rotherham": "Unto whom couldst thou be likened thus, in glory and in greatness, among the trees of Eden? Yet shalt thou be caused to descend with the trees of Eden into the earth below In the midst of the uncircumcised, shalt thou lie down With them who were thrust through by the sword, the same, is Pharaoh and all his multitude, Declareth My Lord Yahweh.", "darby": "To whom art thou thus like in glory and in greatness among the trees of Eden? Yet shalt thou be brought down with the trees of Eden, unto the lower parts of the earth; thou shalt lie in the midst of the uncircumcised, with them that are slain by the sword. This is Pharaoh and all his multitude, saith the Lord Jehovah.", "twenty": "", "jps": "To whom art thou thus like in glory and in greatness among the trees of Eden? yet shall thou be brought down with the trees of Eden unto the nether parts of the earth; thou shalt lie in the midst of the uncircumcised, with them that are slain by the sword. This is Pharaoh and all his multitude, saith the L-rd GOD.'", "acv": "To whom are thou thus like in glory and in greatness among the trees of Eden? Yet thou shall be brought down with the trees of Eden to the nether parts of the earth. Thou shall lie in the midst of the uncircumcised, with those who are slain by the sword. This is Pharaoh and all his multitude, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "To whom art thou thus like in glory and greatness among the trees of Eden? Thou shalt be brought down with the trees of Eden To the lower parts of the earth; Thou shalt lie down in the midst of the uncircumcised, With them that are slain by the sword. Thus shall it be with Pharaoh and all his multitude, Saith the Lord Jehovah.", "webster": "To whom art thou thus like in glory and in greatness among the trees of Eden? yet shalt thou be brought down with the trees of Eden to the nether parts of the earth: thou shalt lie in the midst of the uncircumcised with [them that are] slain by the sword. This [is] Pharaoh and all his multitude, saith the Lord GOD.", "vulgate": "cui adsimilatus es o inclite atque sublimis inter ligna voluptatis ecce deductus es cum lignis voluptatis ad terram ultimam in medio incircumcisorum dormies cum his qui interfecti sunt gladio ipse est Pharao et omnis multitudo eius dicit Dominus Deus;", "brenton": "To whom art thou compared? descend, and be thou debased with the trees of paradise to the depth of the earth: thou shalt lie in the midst of the uncircumcised with them that are slain by the sword. Thus shall Pharao be, and the multitude of his host, saith the Lord God."}}]}, {"c": 32, "verses": [{"v": 1, "ref": "32:1", "o": "וַֽ/יְהִי֙ בִּ/שְׁתֵּ֣י עֶשְׂרֵ֣ה שָׁנָ֔ה בִּ/שְׁנֵי עָשָׂ֥ר חֹ֖דֶשׁ בְּ/אֶחָ֣ד לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of the Lord came unto me, saying,", "web": "In the twelfth year, in the twelfth month, in the first day of the month, Yahweh’s word came to me, saying,", "bsb": "In the twelfth year, on the first day of the twelfth month, the word of the LORD came to me, saying,", "asv": "And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the twelfth year, in the twelfth month, in the first of the month, hath a word of Jehovah been unto me, saying,", "dra": "And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of the Lord came to me, saying:", "bbe": "And it came about in the twelfth year, in the twelfth month, on the first day of the month, that the word of the Lord came to me, saying,", "geneva": "And in the twelfth yeere in the twelfth moneth, and in the first day of the moneth, the worde of the Lord came vnto me, saying,", "wycliffe": "And it was don in the tweluethe yeer, in the tweluethe monethe, in the firste dai of the monethe, the word of the Lord was maad to me,", "rotherham": "And it came to pass, in the twelfth year, in the twelfth month on the first of the month, that the word of Yahweh came unto me, saying:", "darby": "And it came to pass in the twelfth year, in the twelfth month, on the first of the month, that the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of HaShem came unto me, saying:", "acv": "And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And it came to pass in the twelfth year, in the twelfth month, on the first day of the month, that the word of Jehovah came to me, saying:", "webster": "And it came to pass in the twelfth year, in the twelfth month, in the first [day] of the month, [that] the word of the LORD came to me, saying,", "vulgate": "et factum est duodecimo anno in mense duodecimo in una mensis factum est verbum Domini ad me dicens;", "brenton": "And it came to pass in the twelfth year, in the tenth month, on the first day of the month, that the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "32:2", "o": "בֶּן אָדָ֗ם שָׂ֤א קִינָה֙ עַל פַּרְעֹ֣ה מֶֽלֶךְ מִצְרַ֔יִם וְ/אָמַרְתָּ֣ אֵלָ֔י/ו כְּפִ֥יר גּוֹיִ֖ם נִדְמֵ֑יתָ וְ/אַתָּה֙ כַּ/תַּנִּ֣ים בַּ/יַּמִּ֔ים וַ/תָּ֣גַח בְּ/נַהֲרוֹתֶ֗י/ךָ וַ/תִּדְלַח מַ֨יִם֙ בְּ/רַגְלֶ֔י/ךָ וַ/תִּרְפֹּ֖ס נַהֲרוֹתָֽ/ם", "en": {"kjv": "Son of man, take up a lamentation for Pharaoh king of Egypt, and say unto him, Thou art like a young lion of the nations, and thou art as a whale in the seas: and thou camest forth with thy rivers, and troubledst the waters with thy feet, and fouledst their rivers.", "web": "Son of man, take up a lamentation over Pharaoh king of Egypt, and tell him, You were likened to a young lion of the nations: yet you are as a monster in the seas; and you broke out with your rivers, and troubled the waters with your feet, and fouled their rivers.", "bsb": "“Son of man, take up a lament for Pharaoh king of Egypt and say to him: ‘You are like a lion among the nations; you are like a monster in the seas. You thrash about in your rivers, churning up the waters with your feet and muddying the streams.’", "asv": "Son of man, take up a lamentation over Pharaoh king of Egypt, and say unto him, Thou wast likened unto a young lion of the nations: yet art thou as a monster in the seas; and thou didst break forth with thy rivers, and troubledst the waters with thy feet, and fouledst their rivers.", "ylt": "`Son of man, lift up a lamentation for Pharaoh king of Egypt, and thou hast said unto him: A young lion of nations thou hast been like, And thou art as a dragon in the seas, And thou comest forth with thy flowings, And dost trouble the waters with thy feet, And thou dost foul their flowings.", "dra": "Son of man, take up a lamentation for Pharao the king of Egypt, and say to him: Thou art like the lion of the nations, and the dragon that is in the sea: and thou didst push with the horn in thy rivers, and didst trouble the waters with thy feet, and didst trample upon their streams.", "bbe": "Son of man, make a song of grief for Pharaoh, king of Egypt, and say to him, Young lion of the nations, destruction has come on you; and you were like a sea-beast in the seas, sending out bursts of water, troubling the waters with your feet, making their streams dirty.", "geneva": "Sonne of man, take vp a lamentation for Pharaoh King of Egypt, and say vnto him, Thou art like a lyon of the nations and art as a dragon in the sea: thou castedst out thy riuers and troubledst the waters with thy feete, and stampedst in their riuers.", "wycliffe": "and he seide, Thou, sone of man, take weilyng on Farao, kyng of Egipt, and thou schalt seie to hym, Thou were maad lijk to a lioun of hethene men, and to a dragoun whiche is in the see. And thou wyndewist with horn in thi floodis, and thou disturblidist watris with thi feet, and defoulidist the floodis of tho.", "rotherham": "Son of man Take up a dirge over Pharaoh king of Egypt, and thou shalt say unto him. The young lion of the nations, thou didst deem thyself,- Whereas thou, wast like the crocodile in the seas, And didst cause thy streams to burst forth And didst trouble the waters with thy feet, And foul their rivers.", "darby": "Son of man, take up a lamentation for Pharaoh king of Egypt, and say unto him, Thou wast like a young lion among the nations, and thou wast as a monster in the seas; and thou didst break forth in thy rivers, and troubledst the waters with thy feet, and fouledst their rivers.", "twenty": "", "jps": "'Son of man, take up a lamentation for Pharaoh king of Egypt, and say unto him: thou didst liken thyself unto a young lion of the nations; whereas thou art as a dragon in the seas; and thou didst gush forth with thy rivers, and didst trouble the waters with thy feet, and foul their rivers.", "acv": "Son of man, take up a lamentation over Pharaoh king of Egypt, and say to him, Thou were compared to a young lion of the nations. Yet thou are as a monster in the seas, and thou broke forth with thy rivers, and troubled the waters with thy feet, and fouled their rivers.", "anderson": "", "haweis": "", "noyes": "Son of man, take up a lamentation over Pharaoh, the king of Egypt, and say to him:—Thou art like a young lion among the nations; Thou art like a dragon in the seas; And thou camest forth into thy rivers, And troubledst the waters with thy feet, And didst disturb their rivers.", "webster": "Son of man, take up a lamentation for Pharaoh king of Egypt, and say to him, Thou art like a young lion of the nations, and thou [art] as a whale in the seas: and thou didst come forth with thy rivers, and disturb the waters with thy feet, and render their rivers foul.", "vulgate": "fili hominis adsume lamentum super Pharao regem Aegypti et dices ad eum leoni gentium adsimilatus es et draconi qui est in mari et ventilabas cornu in fluminibus tuis et conturbabas aquas pedibus tuis et conculcabas flumina eorum;", "brenton": "Son of man, take up a lamentation for Pharao king of Egypt, and say to him, Thou art become like a lion of the nations, and as a serpent that is in the sea: and thou didst make assaults with thy rivers, and didst disturb the water with thy feet, and didst trample thy rivers."}}, {"v": 3, "ref": "32:3", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה וּ/פָרַשְׂתִּ֤י עָלֶ֨י/ךָ֙ אֶת רִשְׁתִּ֔/י בִּ/קְהַ֖ל עַמִּ֣ים רַבִּ֑ים וְ/הֶעֱל֖וּ/ךָ בְּ/חֶרְמִֽ/י", "en": {"kjv": "Thus saith the Lord God; I will therefore spread out my net over thee with a company of many people; and they shall bring thee up in my net.", "web": "Thus says the Lord Yahweh: I will spread out my net on you with a company of many peoples; and they shall bring you up in my net.", "bsb": "This is what the Lord GOD says: ‘I will spread My net over you with a company of many peoples, and they will draw you up in My net.", "asv": "Thus saith the Lord Jehovah: I will spread out my net upon thee with a company of many peoples; and they shall bring thee up in my net.", "ylt": "Thus said the Lord Jehovah: And--I have spread out for thee My net, With an assembly of many peoples, And they have brought thee up in My net.", "dra": "Therefore, thus saith the Lord God: I will spread out my net over thee with the multitude of many people, and I will draw thee up in my net.", "bbe": "This is what the Lord has said: My net will be stretched out over you, and I will take you up in my fishing-net.", "geneva": "Thus sayth the Lord God, I will therefore spread my net ouer thee with a great multitude of people, and they shall make thee come vp into my net.", "wycliffe": "Therfor the Lord God seith these thingis, Y schal spredde abrood my net on thee in the multitude of many puples, and Y schal drawe thee out in my net;", "rotherham": "Thus saith My Lord, Yahweh, Therefore will I spread over thee my net, With a gathered host of many peoples,-And they shall bring thee up in my net;", "darby": "Thus saith the Lord Jehovah: I will also spread out my net over thee with an assemblage of many peoples; and they shall bring thee up in my net.", "twenty": "", "jps": "Thus saith the L-rd GOD: I will therefore spread out My net over thee with a company of many peoples; and they shall bring thee up in My net.", "acv": "Thus says the lord Jehovah: I will spread out my net upon thee with a company of many peoples, and they shall bring thee up in my net.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I will therefore spread my net over thee, Amidst an assembly of many nations; And they shall draw thee up in my net.", "webster": "Thus saith the Lord GOD; I will therefore spread out my net over thee with a company of many people; and they shall bring thee up in my net.", "vulgate": "propterea haec dicit Dominus Deus expandam super te rete meum in multitudine populorum multorum et extrahent te in sagena mea;", "brenton": "Thus saith the Lord; I will also cast over thee the nets of many nations, and will bring thee up with my hook:"}}, {"v": 4, "ref": "32:4", "o": "וּ/נְטַשְׁתִּ֣י/ךָ בָ/אָ֔רֶץ עַל פְּנֵ֥י הַ/שָּׂדֶ֖ה אֲטִילֶ֑/ךָ וְ/הִשְׁכַּנְתִּ֤י עָלֶ֨י/ךָ֙ כָּל ע֣וֹף הַ/שָּׁמַ֔יִם וְ/הִשְׂבַּעְתִּ֥י מִמְּ/ךָ֖ חַיַּ֥ת כָּל הָ/אָֽרֶץ", "en": {"kjv": "Then will I leave thee upon the land, I will cast thee forth upon the open field, and will cause all the fowls of the heaven to remain upon thee, and I will fill the beasts of the whole earth with thee.", "web": "I will leave you on the land, I will cast you out on the open field, and will cause all the birds of the sky to settle on you, and I will satisfy the animals of the whole earth with you.", "bsb": "I will abandon you on the land and hurl you into the open field. I will cause all the birds of the air to settle upon you, and all the beasts of the earth to eat their fill of you.", "asv": "And I will leave thee upon the land, I will cast thee forth upon the open field, and will cause all the birds of the heavens to settle upon thee, and I will satisfy the beasts of the whole earth with thee.", "ylt": "And I have left thee in the land, On the face of the field I do cast thee out, And have caused to dwell upon thee every fowl of the heavens, And have satisfied out of thee the beasts of the whole earth.", "dra": "And I will throw thee out on the land, I will cast thee away into the open field and I will cause all the fowls of the air to dwell upon thee, and I will fill the beasts of all the earth with thee.", "bbe": "And I will let you be stretched on the land; I will send you out violently into the open field; I will let all the birds of heaven come to rest on you and will make the beasts of all the earth full of you.", "geneva": "Then will I leaue thee vpon the land, and I will cast thee vpon the open field, and I wil cause all the foules of the heauen to remaine vpon thee, and I will fill all the beastes of the field with thee.", "wycliffe": "and Y schal caste forth thee in to erthe. On the face of the feeld Y schal caste thee awei, and Y schal make alle the volatils of heuene to dwelle on thee, and Y schal fille of thee the beestis of al erthe.", "rotherham": "And I will stretch thee out on the land, Over the face of the field, will I fling thee,- And will cause to settle upon thee all the birds of the heavens, And will satiate with thee the wild beasts of all the earth;", "darby": "And I will leave thee upon the land, I will cast thee forth upon the open field, and will cause all the fowl of the heavens to settle upon thee, and I will fill the beasts of the whole earth with thee.", "twenty": "", "jps": "And I will cast thee upon the land, I will hurl thee upon the open field, and will cause all the fowls of the heaven to settle upon thee, and I will fill the beasts of the whole earth with thee.", "acv": "And I will leave thee upon the land. I will cast thee forth upon the open field, and will cause all the birds of the heavens to settle upon thee, and I will satisfy the beasts of the whole earth with thee.", "anderson": "", "haweis": "", "noyes": "And I will throw thee upon the land, I will cast thee forth upon the open field, And I will cause all the birds of heaven to remain upon thee. And I will fill the beasts of the whole earth with thee;", "webster": "Then will I leave thee upon the land, and I will cast thee forth upon the open field, and will cause all the fowls of the heaven to remain upon thee, and I will fill the beasts of the whole earth with thee.", "vulgate": "et proiciam te in terram super faciem agri abiciam te et habitare faciam super te omnia volatilia caeli et saturabo de te bestias universae terrae;", "brenton": "and I will stretch thee upon the earth: the fields shall be covered with thee, and I will cause all the birds of the sky to settle upon thee, and I will fill with thee all the wild beasts of the earth."}}, {"v": 5, "ref": "32:5", "o": "וְ/נָתַתִּ֥י אֶת בְּשָׂרְ/ךָ֖ עַל הֶֽ/הָרִ֑ים וּ/מִלֵּאתִ֥י הַ/גֵּאָי֖וֹת רָמוּתֶֽ/ךָ", "en": {"kjv": "And I will lay thy flesh upon the mountains, and fill the valleys with thy height.", "web": "I will lay your flesh on the mountains, and fill the valleys with your height.", "bsb": "I will put your flesh on the mountains and fill the valleys with your remains.", "asv": "And I will lay thy flesh upon the mountains, and fill the valleys with thy height.", "ylt": "And I have put thy flesh on the mountains, And filled the valleys with thy hugeness,", "dra": "And I will lay thy flesh upon the mountains, and will fill thy hills with thy corruption,", "bbe": "And I will put your flesh on the mountains, and make the valleys full of your blood.", "geneva": "And I will lay thy flesh vpon the mountaines, and fill the valleys with thine height.", "wycliffe": "And Y schal yyue thi fleischis on hillis, and Y schal fille thi litle hillis with thi root;", "rotherham": "And I will lay thy flesh on the mountains,— And fill the valleys, with thy blood;", "darby": "And I will lay thy flesh upon the mountains, and fill the valleys with the heap of thy [members];", "twenty": "", "jps": "And I will lay thy flesh upon the mountains, and fill the valleys with thy foulness.", "acv": "And I will lay thy flesh upon the mountains, and fill the valleys with thy height.", "anderson": "", "haweis": "", "noyes": "And I will lay thy flesh upon the mountains, And fill the valleys with thy heaps.", "webster": "And I will lay thy flesh upon the mountains, and fill the valleys with thy hight.", "vulgate": "et dabo carnes tuas super montes et implebo colles tuos sanie tua;", "brenton": "And I will cast thy flesh upon the mountains, and will saturate them with thy blood."}}, {"v": 6, "ref": "32:6", "o": "וְ/הִשְׁקֵיתִ֨י אֶ֧רֶץ צָפָתְ/ךָ֛ מִ/דָּמְ/ךָ֖ אֶל הֶֽ/הָרִ֑ים וַ/אֲפִקִ֖ים יִמָּלְא֥וּ/ן מִמֶּֽ/ךָּ", "en": {"kjv": "I will also water with thy blood the land wherein thou swimmest, even to the mountains; and the rivers shall be full of thee.", "web": "I will also water with your blood the land in which you swim, even to the mountains; and the watercourses shall be full of you.", "bsb": "I will drench the land with the flow of your blood, all the way to the mountains— the ravines will be filled.", "asv": "I will also water with thy blood the land wherein thou swimmest, even to the mountains; and the watercourses shall be full of thee.", "ylt": "And watered the land with thy flowing, From thy blood--unto the mountains, And streams are filled from thee.", "dra": "And I will water the earth with thy stinking blood upon the mountains, and the valleys shall be filled with thee.", "bbe": "And the land will be watered with your blood, and the waterways will be full of you.", "geneva": "I will also water with thy blood the land wherein thou swimmest, euen to ye mountaines, and the riuers shall be full of thee.", "wycliffe": "and Y schal moiste the erthe with the stynk of thi blood on mounteyns, and valeis schulen be fillid of thee.", "rotherham": "And will soak the earth with thy blood, amongst the mountains,- And the channels shall be filled with thee.", "darby": "and I will water with thy blood the land wherein thou swimmest, even to the mountains; and the water-courses shall be full of thee.", "twenty": "", "jps": "I will also water with thy blood the land wherein thou swimmest, even to the mountains; and the channels shall be full of thee.", "acv": "I will also water the land, in which thou swim, with thy blood, even to the mountains. And the watercourses shall be full of thee.", "anderson": "", "haweis": "", "noyes": "And I will water the land in which thou swimmest with thy blood, even to the mountains, And the streams shall be full of thee.", "webster": "I will also water with thy blood the land in which thou swimmest, [even] to the mountains; and the rivers shall be full of thee.", "vulgate": "et inrigabo terram pedore sanguinis tui super montes et valles implebuntur ex te;", "brenton": "And the land shall be drenched with thy dung, because of thy multitude upon the mountains: I will fill the valleys with thee."}}, {"v": 7, "ref": "32:7", "o": "וְ/כִסֵּיתִ֤י בְ/כַבּֽוֹתְ/ךָ֙ שָׁמַ֔יִם וְ/הִקְדַּרְתִּ֖י אֶת כֹּֽכְבֵי/הֶ֑ם שֶׁ֚מֶשׁ בֶּ/עָנָ֣ן אֲכַסֶּ֔/נּוּ וְ/יָרֵ֖חַ לֹא יָאִ֥יר אוֹרֽ/וֹ", "en": {"kjv": "And when I shall put thee out, I will cover the heaven, and make the stars thereof dark; I will cover the sun with a cloud, and the moon shall not give her light.", "web": "When I shall extinguish you, I will cover the heavens, and make its stars dark; I will cover the sun with a cloud, and the moon shall not give its light.", "bsb": "When I extinguish you, I will cover the heavens and darken their stars. I will cover the sun with a cloud, and the moon will not give its light.", "asv": "And when I shall extinguish thee, I will cover the heavens, and make the stars thereof dark; I will cover the sun with a cloud, and the moon shall not give its light.", "ylt": "And in quenching thee I have covered the heavens, And have made black their stars, The sun with a cloud I do cover, And the moon causeth not its light to shine.", "dra": "And I will cover the heavens, when thou shalt be put out, and I will make the stars thereof dark: I will cover the sun with a cloud, and the moon shall not give her light.", "bbe": "And when I put out your life, the heaven will be covered and its stars made dark; I will let the sun be covered with a cloud and the moon will not give her light.", "geneva": "And when I shall put thee out, I will couer the heauen, and make the starres thereof darke: I will couer the sunne with a cloude, and the moone shall not giue her light.", "wycliffe": "And whanne thou schalt be quenchid, Y schal hile heuenes, and Y schal make blak the sterris therof; Y schal kyuere the sunne with a clowde, and the moone schal not yyue hir liyt.", "rotherham": "And when I quench thee, I will cover the heavens, And obscure their stars,— The sun—with a cloud, will I cover, And the moon shall not shed her light;", "darby": "And when I shall put thee out, I will cover the heavens, and make the stars thereof black; I will cover the sun with a cloud, and the moon shall not give her light.", "twenty": "", "jps": "And when I shall extinguish thee, I will cover the heaven, and make the stars thereof black; I will cover the sun with a cloud, and the moon shall not give her light.", "acv": "And when I shall extinguish thee, I will cover the heavens, and make the stars of it dark. I will cover the sun with a cloud, and the moon shall not give its light.", "anderson": "", "haweis": "", "noyes": "And I will cover the heavens, when I quench thee, And make the stars thereof dark; I will cover the sun with a cloud, And the moon shall not give her light.", "webster": "And when I shall extinguish thee, I will cover the heaven, and make the stars thereof dark; I will cover the sun with a cloud, and the moon shall not give her light.", "vulgate": "et operiam cum extinctus fueris caelos et nigrescere faciam stellas eius solem nube tegam et luna non dabit lumen suum;", "brenton": "And I will veil the heavens when thou art extinguished, and will darken the stars thereof; I will cover the sun with a cloud, and the moon shall not give her light."}}, {"v": 8, "ref": "32:8", "o": "כָּל מְא֤וֹרֵי אוֹר֙ בַּ/שָּׁמַ֔יִם אַקְדִּירֵ֖/ם עָלֶ֑י/ךָ וְ/נָתַ֤תִּי חֹ֨שֶׁךְ֙ עַֽל אַרְצְ/ךָ֔ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "All the bright lights of heaven will I make dark over thee, and set darkness upon thy land, saith the Lord God.", "web": "All the bright lights of the sky will I make dark over you, and set darkness on your land, says the Lord Yahweh.", "bsb": "All the shining lights in the heavens I will darken over you, and I will bring darkness upon your land,’ declares the Lord GOD.", "asv": "All the bright lights of heaven will I make dark over thee, and set darkness upon thy land, saith the Lord Jehovah.", "ylt": "All luminaries of light in the heavens, I make black over thee, And I have given darkness over thy land, An affirmation of the Lord Jehovah,", "dra": "I will make all the lights of heaven to mourn over thee and I will cause darkness upon thy land, saith the Lord God, when thy wounded shall fall in the midst of the land, saith the Lord God.", "bbe": "All the bright lights of heaven I will make dark over you, and put dark night on your land, says the Lord.", "geneva": "All the lightes of heauen will I make darke for thee, and bring darkenesse vpon thy lande, sayeth the Lord God.", "wycliffe": "Y schal make alle the liyt yyueris of heuene to mourne on thee, and Y schal yyue derknessis on thi lond, seith the Lord God; whanne thi woundid men schulen falle doun in the myddis of erthe, seith the Lord God.", "rotherham": "As for all the light-bearers in the heavens, I will obscure them over thee— And will stretch out darkness over thy land, Declareth My Lord Yahweh.", "darby": "All the bright lights of the heavens will I make black over thee, and bring darkness upon thy land, saith the Lord Jehovah.", "twenty": "", "jps": "All the bright lights of heaven will I make black over thee, and set darkness upon thy land, saith the L-rd GOD.", "acv": "All the bright lights of heaven I will make dark over thee, and set darkness upon thy land, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "All the bright lights of heaven will I make dark over thee, And bring darkness upon thy land, Saith the Lord Jehovah.", "webster": "All the bright lights of heaven will I make dark over thee, and set darkness upon thy land, saith the Lord GOD.", "vulgate": "omnia luminaria caeli maerere faciam super te et dabo tenebras super terram tuam dicit Dominus Deus;", "brenton": "All the bodies that give light in the sky, shall be darkened over thee, and I will bring darkness upon the earth, saith the Lord God."}}, {"v": 9, "ref": "32:9", "o": "וְ/הִ֨כְעַסְתִּ֔י לֵ֖ב עַמִּ֣ים רַבִּ֑ים בַּ/הֲבִיאִ֤/י שִׁבְרְ/ךָ֙ בַּ/גּוֹיִ֔ם עַל אֲרָצ֖וֹת אֲשֶׁ֥ר לֹֽא יְדַעְתָּֽ/ם", "en": {"kjv": "I will also vex the hearts of many people, when I shall bring thy destruction among the nations, into the countries which thou hast not known.", "web": "I will also trouble the hearts of many peoples, when I shall bring your destruction among the nations, into the countries which you have not known.", "bsb": "‘I will trouble the hearts of many peoples, when I bring about your destruction among the nations, in countries you do not know.", "asv": "I will also vex the hearts of many peoples, when I shall bring thy destruction among the nations, into the countries which thou hast not known.", "ylt": "And I have vexed the heart of many peoples, In My bringing in thy destruction among nations, Unto lands that thou hast not known.", "dra": "And I shall provoke to anger the heart of many people, when I shall have brought in thy destruction among the nations upon the lands, which thou knowest not.", "bbe": "And the hearts of numbers of peoples will be troubled, when I send your prisoners among the nations, into a country which is strange to you.", "geneva": "I will also trouble the heartes of many people, when I shall bring thy destruction among the nations and vpon the countries which thou hast not knowen.", "wycliffe": "And Y schal terre to wraththe the herte of many puplis, whanne Y schal bringe in thi sorewe among folkis, on londis whiche thou knowist not.", "rotherham": "And I will aggrieve the heart of many peoples,- when I bring them who are broken off from thee among the nations, unto lands which thou hast not known.", "darby": "And I will vex the heart of many peoples, when I bring [the news of] thy destruction among the nations, into the countries that thou hast not known.", "twenty": "", "jps": "I will also vex the hearts of many peoples, when I shall bring thy destruction among the nations, into the countries which thou hast not known.", "acv": "I will also vex the hearts of many peoples when I shall bring thy destruction among the nations, into the countries which thou have not known.", "anderson": "", "haweis": "", "noyes": "And I will grieve the hearts of many nations, When I bring thy destruction among the nations, In lands which thou knowest not.", "webster": "I will also vex the hearts of many people, when I shall bring thy destruction among the nations, into the countries which thou hast not known.", "vulgate": "et inritabo cor populorum multorum cum induxero contritionem tuam in gentibus super terras quas nescis;", "brenton": "And I will provoke to anger the heart of many people, when I shall lead thee captive among the nations, to a land which thou hast not known."}}, {"v": 10, "ref": "32:10", "o": "וַ/הֲשִׁמּוֹתִ֨י עָלֶ֜י/ךָ עַמִּ֣ים רַבִּ֗ים וּ/מַלְכֵי/הֶם֙ יִשְׂעֲר֤וּ עָלֶ֨י/ךָ֙ שַׂ֔עַר בְּ/עוֹפְפִ֥/י חַרְבִּ֖/י עַל פְּנֵי/הֶ֑ם וְ/חָרְד֤וּ לִ/רְגָעִים֙ אִ֣ישׁ לְ/נַפְשׁ֔/וֹ בְּ/י֖וֹם מַפַּלְתֶּֽ/ךָ", "en": {"kjv": "Yea, I will make many people amazed at thee, and their kings shall be horribly afraid for thee, when I shall brandish my sword before them; and they shall tremble at every moment, every man for his own life, in the day of thy fall.", "web": "Yes, I will make many peoples amazed at you, and their kings shall be horribly afraid for you, when I shall brandish my sword before them; and they shall tremble at every moment, every man for his own life, in the day of your fall.", "bsb": "I will cause many peoples to be appalled over you, and their kings will shudder in horror because of you when I brandish My sword before them. On the day of your downfall each of them will tremble every moment for his life.’", "asv": "Yea, I will make many peoples amazed at thee, and their kings shall be horribly afraid for thee, when I shall brandish my sword before them; and they shall tremble at every moment, every man for his own life, in the day of thy fall.", "ylt": "And I have made many peoples astonished at thee, And their kings are afraid at thee with trembling, In My brandishing My sword before their faces, And they have trembled every moment, Each for his life--in the day of thy fall.", "dra": "And I will make many people to be amazed at thee, and their kings shall be horribly afraid for thee, when my sword shall begin to fly upon their faces: and they shall be astonished on a sudden, every one for his own life, in the day of their ruin.", "bbe": "And I will make a number of peoples overcome with wonder at you, and their kings will be full of fear because of you, when my sword is waved before them: they will be shaking every minute, every man fearing for his life, in the day of your fall.", "geneva": "Yea, I will make many people amased at thee, and their Kings shalbe astonished with feare for thee, when I shall make my sworde to glitter against their faces, and they shall be afraide at euery moment: euery man for his owne life in the day of thy fall.", "wycliffe": "And Y schal make many puplis to wondre on thee, and the kyngis of hem schulen drede with ful greet hidousnesse on thee, for alle thi wickidnessis whiche thou wrouytist, whanne my swerd schal bigynne to flee on the faces of hem. And alle men schulen be astonyed sudenli, for her lijf, in the dai of her fallyng.", "rotherham": "Yea I will cause amazement over thee unto many peoples And the hair of their kings shall stand on end over thee, when I brandish my sword over their faces,- And they shall tremble every moment every man for his own life, In the day of thy fall.", "darby": "And I will make many peoples amazed at thee, and their kings shall be horribly afraid at thee, when I brandish my sword before them; and they shall tremble at every moment, each one for his life, in the day of thy fall.", "twenty": "", "jps": "Yea, I will make many peoples appalled at thee, and their kings shall be horribly afraid for thee, when I shall brandish My sword before them; and they shall tremble at every moment, every man for his own life, in the day of thy fall.", "acv": "Yea, I will make many peoples amazed at thee. And their kings shall be horribly afraid for thee when I shall brandish my sword before them. And they shall tremble at every moment, each man for his own life, in the day of thy fall.", "anderson": "", "haweis": "", "noyes": "Yea, I will make many people amazed at thee, And their kings shall shudder on account of thee, When I brandish my sword before them; And they shall tremble every moment, every one for his life, in the day of thy fall.", "webster": "Yes, I will make many people amazed at thee, and their kings shall be horribly afraid for thee, when I shall brandish my sword before them; and they shall tremble at [every] moment, every man for his own life, in the day of thy fall.", "vulgate": "et stupescere faciam super te populos multos et reges eorum horrore nimio formidabunt super te cum volare coeperit gladius meus super facies eorum et obstupescent repente singuli pro anima sua in die ruinae suae;", "brenton": "And many nations shall mourn over thee, and their kings shall be utterly amazed, when my sword flies in their faces, as they wait for their own fall from the day of thy fall."}}, {"v": 11, "ref": "32:11", "o": "כִּ֛י כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה חֶ֥רֶב מֶֽלֶךְ בָּבֶ֖ל תְּבוֹאֶֽ/ךָ", "en": {"kjv": "For thus saith the Lord God; The sword of the king of Babylon shall come upon thee.", "web": "For thus says the Lord Yahweh: The sword of the king of Babylon shall come on you.", "bsb": "For this is what the Lord GOD says: ‘The sword of the king of Babylon will come against you!", "asv": "For thus saith the Lord Jehovah: The sword of the king of Babylon shall come upon thee.", "ylt": "For thus said the Lord Jehovah: A sword of the king of Babylon entereth thee,", "dra": "For thus saith the Lord God: The sword of the king of Babylon shall come upon thee,", "bbe": "For this is what the Lord has said: The sword of the king of Babylon will come on you.", "geneva": "For thus sayth the Lord God, The sworde of the King of Babel shall come vpon thee.", "wycliffe": "For the Lord God seith these thingis, The swerd of the king of Babiloyne schal come to thee;", "rotherham": "For thus saith My Lord, Yahweh:-the sword of the king of Babylon shall reach thee.", "darby": "For thus saith the Lord Jehovah: The sword of the king of Babylon shall come upon thee.", "twenty": "", "jps": "For thus saith the L-rd GOD: The sword of the king of Babylon shall come upon thee.", "acv": "For thus says the lord Jehovah: The sword of the king of Babylon shall come upon thee.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: The sword of the king of Babylon shall come upon thee;", "webster": "For thus saith the Lord GOD; The sword of the king of Babylon shall come upon thee.", "vulgate": "quia haec dicit Dominus Deus gladius regis Babylonis veniet tibi;", "brenton": "For thus saith the Lord God; The sword of the king of Babylon shall come upon thee,"}}, {"v": 12, "ref": "32:12", "o": "בְּ/חַרְב֤וֹת גִּבּוֹרִים֙ אַפִּ֣יל הֲמוֹנֶ֔/ךָ עָרִיצֵ֥י גוֹיִ֖ם כֻּלָּ֑/ם וְ/שָֽׁדְדוּ֙ אֶת גְּא֣וֹן מִצְרַ֔יִם וְ/נִשְׁמַ֖ד כָּל הֲמוֹנָֽ/הּ", "en": {"kjv": "By the swords of the mighty will I cause thy multitude to fall, the terrible of the nations, all of them: and they shall spoil the pomp of Egypt, and all the multitude thereof shall be destroyed.", "web": "By the swords of the mighty will I cause your multitude to fall; the terrible of the nations are they all: and they shall bring to nothing the pride of Egypt, and all its multitude shall be destroyed.", "bsb": "I will make your hordes fall by the swords of the mighty, the most ruthless of all nations. They will ravage the pride of Egypt and all her multitudes will be destroyed.", "asv": "By the swords of the mighty will I cause thy multitude to fall; the terrible of the nations are they all: and they shall bring to nought the pride of Egypt, and all the multitude thereof shall be destroyed.", "ylt": "By swords of the mighty I cause thy multitude to fall, The terrible of nations--all of them, And they have spoiled the excellency of Egypt, And destroyed hath been all her multitude.", "dra": "By the swords of the mighty I will overthrow thy multitude: all these nations are invincible: and they shall waste the pride of Egypt, and the multitude thereof shall be destroyed.", "bbe": "I will let the swords of the strong be the cause of the fall of your people; all of them men to be feared among the nations: and they will make waste the pride of Egypt, and all its people will come to destruction.", "geneva": "By the swordes of the mightie will I cause thy multitude to fall: they all shall be terrible nations, and they shall destroy the pompe of Egypt, and all the multitude thereof shalbe consumed.", "wycliffe": "in swerdis of stronge men Y schal caste doun thi multitude, alle these folkis ben not able to be ouercomun. And thei schulen waste the pride of Egipt, and the multitude therof schal be distried.", "rotherham": "With the swords of mighty men, will I cause thy multitude to fall, Terrible ones of the nations all of them!-And they shall spoil the pride of Egypt, And all her multitude shall be destroyed,", "darby": "By the swords of the mighty will I cause thy multitude to fall: the terrible of the nations are they all: and they shall spoil the pride of Egypt, and all the multitude thereof shall be destroyed.", "twenty": "", "jps": "By the swords of the mighty will I cause thy multitude to fall; the terrible of the nations are they all; and they shall spoil the pride of Egypt, and all the multitude thereof shall be destroyed.", "acv": "By the swords of the mighty I will cause thy multitude to fall. They are all the terrible of the nations. And they shall bring to nothing the pride of Egypt, and all the multitude of it shall be destroyed.", "anderson": "", "haweis": "", "noyes": "By the swords of the mighty will I cause thy multitude to fall, All of them the terrible of the nations. And they shall bring to nothing the pride of Egypt, And all her multitude shall be destroyed.", "webster": "By the swords of the mighty will I cause thy multitude to fall, the terrible of the nations, all of them: and they shall lay waste the pomp of Egypt, and all its multitude shall be destroyed.", "vulgate": "in gladiis fortium deiciam multitudinem tuam inexpugnabiles gentes omnes heae et vastabunt superbiam Aegypti et dissipabitur multitudo eius;", "brenton": "with the swords of mighty men; and I will cast down thy strength: they are all destroying ones from the nations, and they shall destroy the pride of Egypt, and all her strength shall be crushed."}}, {"v": 13, "ref": "32:13", "o": "וְ/הַֽאֲבַדְתִּי֙ אֶת כָּל בְּהֶמְתָּ֔/הּ מֵ/עַ֖ל מַ֣יִם רַבִּ֑ים וְ/לֹ֨א תִדְלָחֵ֤/ם רֶֽגֶל אָדָם֙ ע֔וֹד וּ/פַרְס֥וֹת בְּהֵמָ֖ה לֹ֥א תִדְלָחֵֽ/ם", "en": {"kjv": "I will destroy also all the beasts thereof from beside the great waters; neither shall the foot of man trouble them any more, nor the hoofs of beasts trouble them.", "web": "I will destroy also all its animals from beside many waters; neither shall the foot of man trouble them any more, nor the hoofs of animals trouble them.", "bsb": "I will slaughter all her cattle beside the abundant waters. No human foot will muddy them again, and no cattle hooves will disturb them.", "asv": "I will destroy also all the beasts thereof from beside many waters; neither shall the foot of man trouble them any more, nor the hoofs of beasts trouble them.", "ylt": "And I have destroyed all her beasts, From beside many waters, And trouble them not doth a foot of man any more, Yea, the hoofs of beasts trouble them not.", "dra": "I will destroy also all the beasts thereof that were beside the great waters: and the foot of man shall trouble them no more, neither shall the hoof of beasts trouble them.", "bbe": "And I will put an end to all her beasts which are by the great waters, and they will never again be troubled by the foot of man or by the feet of beasts.", "geneva": "I will destroy also all the beastes thereof from the great watersides, neither shall the foote of man trouble them any more, nor the hooues of beast trouble them.", "wycliffe": "And Y schal leese alle the beestis therof, that weren on ful many watris; and the foot of a man schal no more troble tho watris, nether the clee of beestis schal troble tho.", "rotherham": "And I will cause to perish all her beasts, from beside the many waters,— And the foot of man shall not trouble them any more, Nor shall hoof of beast, trouble them.", "darby": "And I will destroy all the beasts thereof, from beside the great waters; and the foot of man shall not trouble them any more, nor shall the cloven hoofs of beasts trouble them.", "twenty": "", "jps": "I will destroy also all the beasts thereof from beside many waters; neither shall the foot of man trouble them any more, nor the hoofs of beasts trouble them.", "acv": "I will destroy also all the beasts thereof from beside many waters. Neither the foot of man shall trouble them any more, nor the hoofs of beasts trouble them.", "anderson": "", "haweis": "", "noyes": "I will also destroy all her beasts From beside the great waters; Neither shall the foot of man trouble them any more, Nor shall the hoofs of beasts trouble them.", "webster": "I will destroy also all its beasts from beside the great waters; neither shall the foot of man disturb them any more, nor the hoofs of beasts disturb them.", "vulgate": "et perdam omnia iumenta eius quae erant super aquas plurimas et non conturbabit eas pes hominis ultra neque ungula iumentorum turbabit eas;", "brenton": "And I will destroy all her cattle from beside the great water; and the foot of man shall not trouble it any more, and the step of cattle shall no more trample it."}}, {"v": 14, "ref": "32:14", "o": "אָ֚ז אַשְׁקִ֣יעַ מֵֽימֵי/הֶ֔ם וְ/נַהֲרוֹתָ֖/ם כַּ/שֶּׁ֣מֶן אוֹלִ֑יךְ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Then will I make their waters deep, and cause their rivers to run like oil, saith the Lord God.", "web": "Then will I make their waters clear, and cause their rivers to run like oil, says the Lord Yahweh.", "bsb": "Then I will let her waters settle and will make her rivers flow like oil,’ declares the Lord GOD.", "asv": "Then will I make their waters clear, and cause their rivers to run like oil, saith the Lord Jehovah.", "ylt": "Then do I cause their waters to sink, And their rivers as oil I cause to go, An affirmation of the Lord Jehovah.", "dra": "Then will I make their waters clear, and cause their rivers to run like oil, saith the Lord God:", "bbe": "Then I will make their waters clear and their rivers will be flowing like oil, says the Lord.", "geneva": "Then will I make their waters deepe, and cause their riuers to runne like oyle, sayeth the Lord God.", "wycliffe": "Thanne Y schal yelde the watris of hem clenneste, and Y schal brynge the floodis of hem as oile, seith the Lord God,", "rotherham": "Then, will I make their waters subside, And, their streams—like oil, will I cause to flow,— Declareth My Lord, Yahweh.", "darby": "Then will I make their waters clear, and cause their rivers to run like oil, saith the Lord Jehovah.", "twenty": "", "jps": "Then will I make their waters to settle, and cause their rivers to run like oil, saith the L-rd GOD.", "acv": "Then I will make their waters clear, and cause their rivers to run like oil, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Then will I make their waters clear, And cause their rivers to run like oil, Saith the Lord Jehovah,", "webster": "Then will I make their waters deep, and cause their rivers to run like oil, saith the Lord GOD.", "vulgate": "tunc purissimas reddam aquas eorum et flumina eorum quasi oleum adducam ait Dominus Deus;", "brenton": "Thus shall their waters then be at rest, and their rivers shall flow like oil, saith the Lord,"}}, {"v": 15, "ref": "32:15", "o": "בְּ/תִתִּ/י֩ אֶת אֶ֨רֶץ מִצְרַ֜יִם שְׁמָמָ֣ה וּ/נְשַׁמָּ֗ה אֶ֚רֶץ מִ/מְּלֹאָ֔/הּ בְּ/הַכּוֹתִ֖/י אֶת כָּל י֣וֹשְׁבֵי בָ֑/הּ וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "When I shall make the land of Egypt desolate, and the country shall be destitute of that whereof it was full, when I shall smite all them that dwell therein, then shall they know that I am the Lord.", "web": "When I shall make the land of Egypt desolate and waste, a land destitute of that of which it was full, when I shall strike all those who dwell therein, then shall they know that I am Yahweh.", "bsb": "‘When I make the land of Egypt a desolation and empty it of all that filled it, when I strike down all who live there, then they will know that I am the LORD.’", "asv": "When I shall make the land of Egypt desolate and waste, a land destitute of that whereof it was full, when I shall smite all them that dwell therein, then shall they know that I am Jehovah.", "ylt": "In My making the land of Egypt a desolation, And desolated hath been the land of its fulness, In My smiting all the inhabitants in it, And they have known that I am Jehovah.", "dra": "When I shall have made the land of Egypt desolate: and the land shall be destitute of her fulness, when I shall have struck all the inhabitants thereof and they shall know that I am the Lord.", "bbe": "When I make Egypt an unpeopled waste, cutting off from the land all the things in it; when I send punishment on all those living in it, then it will be clear to them that I am the Lord.", "geneva": "When I shall make the land of Egypt desolate, and the countrey with all that is therein, shall be laid waste: when I shall smite all them which dwell therein, then shall they know that I am ye Lord.", "wycliffe": "whanne Y schal yyue desolat the lond of Egipt. Forsothe the lond schal be forsakun of his fulnesse, whanne Y schal smyte alle the dwellers therof; and thei schulen wite, that Y am the Lord.", "rotherham": "When I make the land of Egypt an astonishment A land laid bare of its fulness, When I cut off all that dwell therein, Then shall they know that, I am Yahweh.", "darby": "When I shall make the land of Egypt a desolation, and the country shall be left desolate of all that was in it, when I have smitten all them that dwell therein, then shall they know that I [am] Jehovah.", "twenty": "", "jps": "When I shall make the land of Egypt desolate and waste, a land destitute of that whereof it was full, when I shall smite all them that dwell therein, then shall they know that I am HaShem.", "acv": "When I shall make the land of Egypt desolate and waste, a land destitute of that of which it was full, when I shall smite all those who dwell therein, then they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "When I shall make the land of Egypt desolate, And the country shall be destitute of all that was therein, When I shall smite all that dwell therein, That they may know that I am Jehovah.", "webster": "When I shall make the land of Egypt desolate, and the country shall be destitute of that of which it was full, when I shall smite all them that dwell in it, then shall they know that I [am] the LORD.", "vulgate": "cum dedero terram Aegypti desolatam deseretur autem terra a plenitudine sua quando percussero omnes habitatores eius et scient quia ego Dominus;", "brenton": "when I shall give up Egypt to destruction, and the land shall be made desolate with the fullness thereof; when I shall scatter all that dwell in it, and they shall know that I am the Lord."}}, {"v": 16, "ref": "32:16", "o": "קִינָ֥ה הִיא֙ וְ/ק֣וֹנְנ֔וּ/הָ בְּנ֥וֹת הַ/גּוֹיִ֖ם תְּקוֹנֵ֣נָּה אוֹתָ֑/הּ עַל מִצְרַ֤יִם וְ/עַל כָּל הֲמוֹנָ/הּ֙ תְּקוֹנֵ֣נָּה אוֹתָ֔/הּ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "This is the lamentation wherewith they shall lament her: the daughters of the nations shall lament her: they shall lament for her, even for Egypt, and for all her multitude, saith the Lord God.", "web": "This is the lamentation with which they shall lament; the daughters of the nations shall lament therewith; over Egypt, and over all her multitude, shall they lament therewith, says the Lord Yahweh.", "bsb": "This is the lament they will chant for her; the daughters of the nations will chant it. Over Egypt and all her multitudes they will chant it, declares the Lord GOD.”", "asv": "This is the lamentation wherewith they shall lament; the daughters of the nations shall lament therewith; over Egypt, and over all her multitude, shall they lament therewith, saith the Lord Jehovah.", "ylt": "A lamentation it is , and they have lamented her, Daughters of the nations do lament her, For Egypt, and for all her multitude, they lament her, An affirmation of the Lord Jehovah.'", "dra": "This is the lamentation, and they shall lament therewith: the daughters of the nations shall lament therewith for Egypt, and for the multitude thereof they shall lament therewith, saith the Lord God.", "bbe": "It is a song of grief, and people will give voice to it, the daughters of the nations will give voice to it, even for Egypt and all her people, says the Lord.", "geneva": "This is the mourning wherewith they shall lament her: the daughters of the nations shall lament her: they shall lament for Egypt, and for all her multitude, sayeth the Lord God.", "wycliffe": "It is a weiling, and the douytris of hethene men schulen biweile hym; thei schulen biweile hym on Egipt, and thei schulen biweile hym on the multitude therof, seith the Lord God.", "rotherham": "A dirge, it is And they shall chant it, The daughters of the nations Shall chant it: Over Egypt and over all her multitude, Shall they chant it, Declareth My Lord, Yahweh.", "darby": "It is a lamentation, and [thus] they shall lament her: the daughters of the nations shall say it in lamenting; they shall say it in lamenting over Egypt and over all her multitude, saith the Lord Jehovah.", "twenty": "", "jps": "This is the lamentation wherewith they shall lament; the daughters of the nations shall lament therewith; for Egypt, and for all her multitude, shall they lament therewith, saith the L-rd GOD.'", "acv": "This is the lamentation with which they shall lament. The daughters of the nations shall lament with that over Egypt, and over all her multitude. They shall lament with that, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "This is the lamentation which they shall utter; the daughters of the nations shall utter it. For Egypt and for all her multitude shall they utter it, saith the Lord Jehovah.", "webster": "This [is] the lamentation with which they shall lament her: the daughters of the nations shall lament her: they shall lament for her, [even] for Egypt, and for all her multitude, saith the Lord GOD.", "vulgate": "planctus est et plangent eum filiae gentium plangent eum super Aegypto et super multitudine eius plangent eum ait Dominus Deus;", "brenton": "There is a lamentation, and thou shalt utter it; and the daughters of the nations shall utter it, even for Egypt, and they shall mourn for it over all the strength thereof, saith the Lord God."}}, {"v": 17, "ref": "32:17", "o": "וַֽ/יְהִי֙ בִּ/שְׁתֵּ֣י עֶשְׂרֵ֣ה שָׁנָ֔ה בַּ/חֲמִשָּׁ֥ה עָשָׂ֖ר לַ/חֹ֑דֶשׁ הָיָ֥ה דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "It came to pass also in the twelfth year, in the fifteenth day of the month, that the word of the Lord came unto me, saying,", "web": "Also in the twelfth year, in the fifteenth day of the month, Yahweh’s word came to me, saying,", "bsb": "In the twelfth year, on the fifteenth day of the month, the word of the LORD came to me, saying,", "asv": "It came to pass also in the twelfth year, in the fifteenth day of the month, that the word of Jehovah came unto me, saying,", "ylt": "And it cometh to pass, in the twelfth year, in the fifteenth of the month, hath a word of Jehovah been unto me, saying,", "dra": "And it came to pass in the twelfth year, in the fifteenth day of the month, that the word of the Lord came to me saying:", "bbe": "And in the twelfth year, on the fifteenth day of the month, the word of the Lord came to me, saying,", "geneva": "In the twelfth yeere also in the fifteenth day of the moneth, came the worde of the Lord vnto me, saying,", "wycliffe": "And it was don in the tweluethe yeer, in the fiftenthe dai of the monethe, the word of the Lord was maad to me,", "rotherham": "And it came to pass in the twelfth year on the fifteenth of the month, that the word of Yahweh came unto me saying:", "darby": "And it came to pass in the twelfth year, on the fifteenth of the month, the word of Jehovah came unto me, saying,", "twenty": "", "jps": "It came to pass also in the twelfth year, in the fifteenth day of the month, that the word of HaShem came unto me, saying:", "acv": "It came to pass also in the twelfth year, in the fifteenth day of the month, that the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "It came to pass also in the twelfth year, [in the twelfth month,] on the fifteenth day of the month, that the word of Jehovah came to me, saying:", "webster": "It came to pass also in the twelfth year, in the fifteenth [day] of the month, [that] the word of the LORD came to me, saying,", "vulgate": "et factum est in duodecimo anno in quintadecima mensis factum est verbum Domini ad me dicens;", "brenton": "And it came to pass in the twelfth year, in the first month, on the fifteenth day of the month, the word of the Lord came to me, saying,"}}, {"v": 18, "ref": "32:18", "o": "בֶּן אָדָ֕ם נְהֵ֛ה עַל הֲמ֥וֹן מִצְרַ֖יִם וְ/הוֹרִדֵ֑/הוּ א֠וֹתָ/הּ וּ/בְנ֨וֹת גּוֹיִ֧ם אַדִּרִ֛ם אֶל אֶ֥רֶץ תַּחְתִּיּ֖וֹת אֶת י֥וֹרְדֵי בֽוֹר", "en": {"kjv": "Son of man, wail for the multitude of Egypt, and cast them down, even her, and the daughters of the famous nations, unto the nether parts of the earth, with them that go down into the pit.", "web": "Son of man, wail for the multitude of Egypt, and cast them down, even her, and the daughters of the famous nations, to the lower parts of the earth, with those who go down into the pit.", "bsb": "“Son of man, wail for the multitudes of Egypt, and consign her and the daughters of the mighty nations to the depths of the earth with those who descend to the Pit:", "asv": "Son of man, wail for the multitude of Egypt, and cast them down, even her, and the daughters of the famous nations, unto the nether parts of the earth, with them that go down into the pit.", "ylt": "`Son of man, Wail for the multitude of Egypt, And cause it to go down, It--and the daughters of honourable nations, Unto the earth--the lower parts, With those going down to the pit.", "dra": "Son of man, sing a mournful song for the multitude of Egypt: and cast her down, both her, and the daughters of the mighty nations to the lowest part of the earth, with them that go down into the pit.", "bbe": "Son of man, let your voice be loud in sorrow for the people of Egypt and send them down, even you and the daughters of the nations; I will send them down into the lowest parts of the earth, with those who go down into the underworld.", "geneva": "Sonne of man, lament for the multitude of Egypt, and cast them downe, euen them and the daughters of the mighty nations vnto the nether partes of the earth, with them that goe downe into the pit.", "wycliffe": "and he seide, Sone of man, synge thou a song of weilyng on the multitude of Egipt, and drawe thou doun it the same, and the douytris of stronge hethene men to the laste lond, with hem that yeden doun in to the lake.", "rotherham": "Son of man Wail thou over the multitude of Egypt and cause it to descend—her and the daughters of the famous nations—into the earth below with them who descend into the pit.", "darby": "Son of man, wail for the multitude of Egypt, and cast them down, her and the daughters of the famous nations, unto the lower parts of the earth, with them that go down into the pit.", "twenty": "", "jps": "'Son of man, wail for the multitude of Egypt, and cast them down, even her, with the daughters of the mighty nations, unto the nether parts of the earth, with them that go down into the pit.", "acv": "Son of man, wail for the multitude of Egypt, and cast them down, even her, and the daughters of the famous nations, to the nether parts of the earth, with those who go down into the pit.", "anderson": "", "haweis": "", "noyes": "Son of man, wail for the multitude of Egypt, and cast her down, even her and the daughters of the famous nations, to the lower parts of the earth, to them that have gone down to the pit.", "webster": "Son of man, wail for the multitude of Egypt, and cast them down, [even] her, and the daughters of the famous nations, to the nether parts of the earth, with them that go down into the pit.", "vulgate": "fili hominis cane lugubre super multitudine Aegypti et detrahe eam ipsam et filias gentium robustarum ad terram ultimam cum his qui descendunt in lacum;", "brenton": "Son of man, lament over the strength of Egypt, for the nations shall bring down her daughters dead to the depth of the earth, to them that go down to the pit."}}, {"v": 19, "ref": "32:19", "o": "מִ/מִּ֖י נָעָ֑מְתָּ רְדָ֥/ה וְ/הָשְׁכְּבָ֖/ה אֶת עֲרֵלִֽים", "en": {"kjv": "Whom dost thou pass in beauty? go down, and be thou laid with the uncircumcised.", "web": "Whom do you pass in beauty? Go down, and be laid with the uncircumcised.", "bsb": "Whom do you surpass in beauty? Go down and be placed with the uncircumcised!", "asv": "Whom dost thou pass in beauty? go down, and be thou laid with the uncircumcised.", "ylt": "Than whom hast thou been more pleasant? Go down, and be laid with the uncircumcised.", "dra": "Whom dost thou excel in beauty? go down and sleep with the uncircumcised.", "bbe": "Are you more beautiful than any? go down, and take your rest among those without circumcision,", "geneva": "Whome doest thou passe in beautie? goe downe and sleepe with the vncircumcised.", "wycliffe": "In as myche as thou art fairere, go doun, and slepe with vncircumcidid men.", "rotherham": "Than whom, art thou more precious? Descend and be laid low with the uncircumcised:", "darby": "Whom dost thou surpass in beauty? Go down, and be thou laid with the uncircumcised.", "twenty": "", "jps": "Whom dost thou pass in beauty? Go down, and be thou laid with the uncircumcised.", "acv": "Whom do thou pass in beauty? Go down, and be thou laid with the uncircumcised.", "anderson": "", "haweis": "", "noyes": "Art thou more beautiful than another? Come down and be laid with the uncircumcised!", "webster": "Whom dost thou pass in beauty? go down, and be thou laid with the uncircumcised.", "vulgate": "quo pulchrior es descende et dormi cum incircumcisis;", "brenton": ""}}, {"v": 20, "ref": "32:20", "o": "בְּ/ת֥וֹךְ חַלְלֵי חֶ֖רֶב יִפֹּ֑לוּ חֶ֣רֶב נִתָּ֔נָה מָשְׁכ֥וּ אוֹתָ֖/הּ וְ/כָל הֲמוֹנֶֽי/הָ", "en": {"kjv": "They shall fall in the midst of them that are slain by the sword: she is delivered to the sword: draw her and all her multitudes.", "web": "They shall fall in the midst of those who are slain by the sword: she is delivered to the sword; draw her away and all her multitudes.", "bsb": "They will fall among those slain by the sword. The sword is appointed! Let them drag her away along with all her multitudes.", "asv": "They shall fall in the midst of them that are slain by the sword: she is delivered to the sword; draw her away and all her multitudes.", "ylt": "In the midst of the pierced of the sword they fall, To the sword she hath been given, They drew her out, and all her multitude.", "dra": "They shall fall in the midst of them that are slain with the sword: the sword is given, they have drawn her down, and all her people.", "bbe": "Among those who have been put to the sword: they will give a resting-place with them to all their people.", "geneva": "They shall fall in the middes of them that are slaine by the sword: shee is deliuered to the sword: draw her downe, and all her multitude.", "wycliffe": "In the myddis of slayn men thei schulen falle doun bi swerd; a swerd is youun, and thei drowen it to, and alle the puplis therof.", "rotherham": "Into the midst of them who were thrust through by the sword, let them fall,-To the sword, hath she been delivered up, Lay ye hold of her and all her multitudes.", "darby": "They shall fall in the midst of them that are slain by the sword. The sword hath been given: draw her out, and all her multitudes.", "twenty": "", "jps": "They shall fall in the midst of them that are slain by the sword; she is delivered to the sword; draw her down and all her multitudes.", "acv": "They shall fall in the midst of those who are slain by the sword. She is delivered to the sword. Draw her away and all her multitudes.", "anderson": "", "haweis": "", "noyes": "They shall fall in the midst of them that are slain by the sword. The sword is given; drag her away and all her multitudes!", "webster": "They shall fall in the midst of [them that are] slain by the sword: she is delivered to the sword: draw her and all her multitudes.", "vulgate": "in medio interfectorum gladio cadent gladius datus est adtraxerunt eam et omnes populos eius;", "brenton": "They shall fall with him in the midst of them that are slain with the sword, and all his strength shall perish: the giants also shall say to thee,"}}, {"v": 21, "ref": "32:21", "o": "יְדַבְּרוּ ל֞/וֹ אֵלֵ֧י גִבּוֹרִ֛ים מִ/תּ֥וֹךְ שְׁא֖וֹל אֶת עֹֽזְרָ֑י/ו יָֽרְד֛וּ שָׁכְב֥וּ הָ/עֲרֵלִ֖ים חַלְלֵי חָֽרֶב", "en": {"kjv": "The strong among the mighty shall speak to him out of the midst of hell with them that help him: they are gone down, they lie uncircumcised, slain by the sword.", "web": "The strong among the mighty shall speak to him out of the midst of Sheol with those who help him: they are gone down, they lie still, even the uncircumcised, slain by the sword.", "bsb": "Mighty chiefs will speak from the midst of Sheol about Egypt and her allies: ‘They have come down and lie with the uncircumcised, with those slain by the sword.’", "asv": "The strong among the mighty shall speak to him out of the midst of Sheol with them that help him: they are gone down, they lie still, even the uncircumcised, slain by the sword.", "ylt": "Speak to him do the gods of the mighty out of the midst of sheol, With his helpers--they have gone down, They have lain with the uncircumcised, The pierced of the sword.", "dra": "The most mighty among the strong ones shall speak to him from the midst of hell, they that went down with his helpers and slept uncircumcised, slain by the sword.", "bbe": "The strong among the great ones will say to him from the underworld, Are you more beautiful than any? go down, you and your helpers, and take your rest among those without circumcision, and those who have been put to the sword.", "geneva": "The most mighty and strong shall speake to him out of the mids of hell with them that helpe her: they are gone downe and sleepe with the vncircumcised that be slaine by the sworde.", "wycliffe": "The myytieste of stronge men schulen speke to hym, fro the myddis of helle, whiche with her helperis yeden doun, and slepten vncircumcidid, and slayn bi swerd.", "rotherham": "The chiefs of the mighty shall speak to him out of the midst of hades, with his helpers,- They have descended They have lain down. The uncircumcised! Thrust through by the sword.", "darby": "The strong among the mighty, with them that helped him, shall speak to him out of the midst of Sheol: they are gone down, they lie still, the uncircumcised, slain by the sword.", "twenty": "", "jps": "The strong among the mighty shall speak of him out of the midst of the nether-world with them that helped him; they are gone down, they lie still, even the uncircumcised, slain by the sword.", "acv": "The strong among the mighty shall speak to him out of the midst of Sheol with those who help him. They have gone down. They lie still, even the uncircumcised, slain by the sword.", "anderson": "", "haweis": "", "noyes": "The mightiest heroes from the midst of the pit shall speak to him and his helpers; For they are gone down, they lie uncircumcised, slain by the sword.", "webster": "The strong among the mighty shall speak to him out of the midst of the grave with them that help him: they are gone down, they lie uncircumcised, slain by the sword.", "vulgate": "loquentur ei potentissimi robustorum de medio inferni qui cum auxiliatoribus eius descenderunt et dormierunt incircumcisi interfecti gladio;", "brenton": "Be thou in the depth of the pit: to whom art thou superior? yea, go down, and lie with the uncircumcised, in the midst of them that are slain with the sword."}}, {"v": 22, "ref": "32:22", "o": "שָׁ֤ם אַשּׁוּר֙ וְ/כָל קְהָלָ֔/הּ סְבִֽיבוֹתָ֖י/ו קִבְרֹתָ֑י/ו כֻּלָּ֣/ם חֲלָלִ֔ים הַ/נֹּפְלִ֖ים בֶּ/חָֽרֶב", "en": {"kjv": "Asshur is there and all her company: his graves are about him: all of them slain, fallen by the sword:", "web": "Asshur is there and all her company; her graves are all around her; all of them slain, fallen by the sword;", "bsb": "Assyria is there with her whole company; her graves are all around her. All of them are slain, fallen by the sword.", "asv": "Asshur is there and all her company; her graves are round about her; all of them slain, fallen by the sword;", "ylt": "There is Asshur, and all her assembly, Round about him are his graves, All of them are wounded, who are falling by sword,", "dra": "Assur is there, and all his multitude: their graves are round about him, all of them slain, and that fell by the sword.", "bbe": "There is Asshur and all her army, round about her last resting-place: all of them put to death by the sword:", "geneva": "Asshur is there and all his companie: their graues are about him: all they are slaine and fallen by the sworde.", "wycliffe": "There is Assur, and al his multitude; the sepulcris of hem ben in the cumpas of hym, alle slayn men, and that fellen doun bi swerd,", "rotherham": "There, is Assyria with all her gathered host, Round about him, are his graves, All of them thrust through, The fallen by the sword:", "darby": "There is Asshur and all his assemblage, his graves round about him: all of them slain, fallen by the sword;", "twenty": "", "jps": "Asshur is there and all her company; their graves are round about them; all of them slain, fallen by the sword;", "acv": "Asshur is there and all her company. Her graves are round about her, all of them slain, fallen by the sword,", "anderson": "", "haweis": "", "noyes": "There is Assyria and all her company; Her graves are round about her; All of them are slain, fallen by the sword;", "webster": "Asshur [is] there and all her company: his graves [are] about him: all of them slain, fallen by the sword:", "vulgate": "ibi Assur et omnis multitudo eius in circuitu illius sepulchra eius omnes interfecti et qui ceciderunt gladio;", "brenton": "There are Assur and all his company: all his slain have been laid there:"}}, {"v": 23, "ref": "32:23", "o": "אֲשֶׁ֨ר נִתְּנ֤וּ קִבְרֹתֶ֨י/הָ֙ בְּ/יַרְכְּתֵי ב֔וֹר וַ/יְהִ֣י קְהָלָ֔/הּ סְבִיב֖וֹת קְבֻרָתָ֑/הּ כֻּלָּ֤/ם חֲלָלִים֙ נֹפְלִ֣ים בַּ/חֶ֔רֶב אֲשֶׁר נָתְנ֥וּ חִתִּ֖ית בְּ/אֶ֥רֶץ חַיִּֽים", "en": {"kjv": "Whose graves are set in the sides of the pit, and her company is round about her grave: all of them slain, fallen by the sword, which caused terror in the land of the living.", "web": "whose graves are set in the uttermost parts of the pit, and her company is around her grave; all of them slain, fallen by the sword, who caused terror in the land of the living.", "bsb": "Her graves are set in the depths of the Pit, and her company is all around her grave. All of them are slain, fallen by the sword— those who once spread terror in the land of the living.", "asv": "whose graves are set in the uttermost parts of the pit, and her company is round about her grave; all of them slain, fallen by the sword, who caused terror in the land of the living.", "ylt": "Whose graves are appointed in the sides of the pit, And her assembly is round about her grave, All of them wounded, falling by sword, Because they gave terror in the land of the living.", "dra": "Whose graves are set in the lowest parts of the pit: and his multitude lay round about his grave: all of them slain, and fallen by the sword, they that heretofore spread terror in the land of the living.", "bbe": "Whose resting-places are in the inmost parts of the underworld, who were a cause of fear in the land of the living.", "geneva": "Whose graues are made in the side of the pit, and his multitude are rounde about his graue: all they are slaine and fallen by the sworde, which caused feare to be in the land of the liuing.", "wycliffe": "whose sepulcris ben youun in the laste thingis of the lake. And the multitude of hym is maad bi the cumpas of his sepulcre, alle slayn men, and fallynge doun bi swerd, whiche yauen sum tyme her ferdfulnesse in the lond of lyuynge men.", "rotherham": "Whose graves have been set In the recesses of the pit, And so her gathered host is round about her grave, All of them thrust through. Fallen by the sword, Who caused terror in the land of the living.", "darby": "their graves are set in the sides of the pit, and his assemblage is round about his grave; all of them slain, fallen by the sword, — who caused terror in the land of the living.", "twenty": "", "jps": "whose graves are set in the uttermost parts of the pit, and her company is round about her grave; all of them slain, fallen by the sword, who caused terror in the land of the living.", "acv": "whose graves are set in the outermost parts of the pit. And her company is round about her grave, all of them slain, fallen by the sword, who caused terror in the land of the living.", "anderson": "", "haweis": "", "noyes": "Her grave is made in the depths of the pit, And her company is round about her grave, All of them slain, fallen by the sword, They who caused terror in the land of the living.", "webster": "Whose graves are set in the sides of the pit, and her company is around her grave: all of them slain, fallen by the sword, who caused terror in the land of the living.", "vulgate": "quorum data sunt sepulchra in novissimis laci et facta est multitudo eius per gyrum sepulchri eius universi interfecti cadentesque gladio qui dederant quondam formidinem in terra viventium;", "brenton": "and their burial is in the depth of the pit, and his company are set around about his tomb: all the slain that fell by the sword, who had caused the fear of them to be upon the land of the living."}}, {"v": 24, "ref": "32:24", "o": "שָׁ֤ם עֵילָם֙ וְ/כָל הֲמוֹנָ֔/הּ סְבִיב֖וֹת קְבֻרָתָ֑/הּ כֻּלָּ֣/ם חֲלָלִים֩ הַ/נֹּפְלִ֨ים בַּ/חֶ֜רֶב אֲֽשֶׁר יָרְד֥וּ עֲרֵלִ֣ים אֶל אֶ֣רֶץ תַּחְתִּיּ֗וֹת אֲשֶׁ֨ר נָתְנ֤וּ חִתִּיתָ/ם֙ בְּ/אֶ֣רֶץ חַיִּ֔ים וַ/יִּשְׂא֥וּ כְלִמָּתָ֖/ם אֶת י֥וֹרְדֵי בֽוֹר", "en": {"kjv": "There is Elam and all her multitude round about her grave, all of them slain, fallen by the sword, which are gone down uncircumcised into the nether parts of the earth, which caused their terror in the land of the living; yet have they borne their shame with them that go down to the pit.", "web": "There is Elam and all her multitude around her grave; all of them slain, fallen by the sword, who are gone down uncircumcised into the lower parts of the earth, who caused their terror in the land of the living, and have borne their shame with those who go down to the pit.", "bsb": "Elam is there with all her multitudes around her grave. All of them are slain, fallen by the sword— those who went down uncircumcised to the earth below, who once spread their terror in the land of the living. They bear their disgrace with those who descend to the Pit.", "asv": "There is Elam and all her multitude round about her grave; all of them slain, fallen by the sword, who are gone down uncircumcised into the nether parts of the earth, who caused their terror in the land of the living, and have borne their shame with them that go down to the pit.", "ylt": "There is Elam, and all her multitude, Round about is her grave, All of them wounded, who are falling by sword, Who have gone down uncircumcised unto the earth--the lower parts, Because they gave their terror in the land of the living, And they bear their shame with those going down to the pit.", "dra": "There is Elam and all his multitude round about his grave, all of them slain, and fallen by the sword; that went down uncircumcised to the lowest parts of the earth: that caused their terror in the land of the living, and they have borne their shame with them that go down into the pit.", "bbe": "There is Elam and all her people, round about her last resting-place: all of them put to death by the sword, who have gone down without circumcision into the lowest parts of the earth, who were a cause of fear in the land of the living, and are put to shame with those who go down to the underworld:", "geneva": "There is Elam and all his multitude round about his graue: al they are slaine and fallen by the sword which are gone downe with the vncircumcised into the nether parts of the earth, which caused themselues to be feared in the land of the liuing, yet haue they borne their shame with them that are gone downe to the pit.", "wycliffe": "There is Helam, and al the multitude therof bi the cumpas of his sepulcre; alle these weren slayn, and fallynge doun bi swerd, that yeden doun vncircumcidid to the laste lond; whiche settiden her drede in the lond of lyuynge men, and baren her schenschipe with hem that goon doun in to the lake.", "rotherham": "There, is Persia with all her multitude, round about her grave,— All of them, thrust through The fallen by the sword Who have descended, uncircumcised into the earth below Who made themselves a terror in the land of the living, And so they have borne their confusion with them who descend into the pit:", "darby": "There is Elam and all her multitude round about her grave, all of them slain, fallen by the sword, who are gone down uncircumcised unto the lower parts of the earth, who caused their terror in the land of the living; yet have they borne their confusion with them that go down to the pit.", "twenty": "", "jps": "There is Elam and all her multitude round about her grave; all of them slain, fallen by the sword, who are gone down uncircumcised into the nether parts of the earth, who caused their terror in the land of the living; yet have they borne their shame with them that go down to the pit.", "acv": "There is Elam and all her multitude round about her grave, all of them slain, fallen by the sword, who have gone down uncircumcised into the nether parts of the earth, who caused their terror in the land of the living, and have borne their shame with those who go down to the pit.", "anderson": "", "haweis": "", "noyes": "There is Elam and all her company round about her grave, All of them slain, fallen by the sword; They are gone down uncircumcised to the lower parts of the earth, Who caused terror in the land of the living; They bear their shame with them that have gone down to the pit.", "webster": "There [is] Elam and all her multitude around her grave, all of them slain, fallen by the sword, who are gone down uncircumcised into the nether parts of the earth, who caused their terror in the land of the living; yet have they borne their shame with them that go down to the pit.", "vulgate": "ibi Aelam et omnis multitudo eius per gyrum sepulchri sui omnes hii interfecti ruentesque gladio qui descenderunt incircumcisi ad terram ultimam qui posuerunt terrorem suum in terra viventium et portaverunt ignominiam suam cum his qui descendunt in lacum;", "brenton": "There is Aelam and all his host round about his tomb: all the slain that fell by the sword, and the uncircumcised that go down to the deep of the earth, who caused their fear to be upon the land of the living: and they have received their punishment with them that go down to the pit,"}}, {"v": 25, "ref": "32:25", "o": "בְּ/ת֣וֹךְ חֲ֠לָלִים נָתְנ֨וּ מִשְׁכָּ֥ב לָ/הּ֙ בְּ/כָל הֲמוֹנָ֔/הּ סְבִֽיבוֹתָ֖י/ו קִבְרֹתֶ֑/הָ כֻּלָּ֣/ם עֲרֵלִ֣ים חַלְלֵי חֶ֡רֶב כִּֽי נִתַּ֨ן חִתִּיתָ֜/ם בְּ/אֶ֣רֶץ חַיִּ֗ים וַ/יִּשְׂא֤וּ כְלִמָּתָ/ם֙ אֶת י֣וֹרְדֵי ב֔וֹר בְּ/ת֥וֹךְ חֲלָלִ֖ים נִתָּֽן", "en": {"kjv": "They have set her a bed in the midst of the slain with all her multitude: her graves are round about him: all of them uncircumcised, slain by the sword: though their terror was caused in the land of the living, yet have they borne their shame with them that go down to the pit: he is put in the midst of them that be slain.", "web": "They have set her a bed in the midst of the slain with all her multitude; her graves are around her; all of them uncircumcised, slain by the sword; for their terror was caused in the land of the living, and they have borne their shame with those who go down to the pit: he is put in the midst of those who are slain.", "bsb": "Among the slain they prepare a resting place for Elam with all her hordes, with her graves all around her. All of them are uncircumcised, slain by the sword, although their terror was once spread in the land of the living. They bear their disgrace with those who descend to the Pit. They are placed among the slain.", "asv": "They have set her a bed in the midst of the slain with all her multitude; her graves are round about her; all of them uncircumcised, slain by the sword; for their terror was caused in the land of the living, and they have borne their shame with them that go down to the pit: he is put in the midst of them that are slain.", "ylt": "In the midst of the wounded they have appointed a bed for her with all her multitude, Round about him are her graves, All of them uncircumcised, pierced of the sword, For their terror was given in the land of the living, And they bear their shame with those going down to the pit, In the midst of the pierced he hath been put.", "dra": "In the midst of the slain they have set him a bed among all his people: their graves are round about him: all these are uncircumcised, and slain by the sword: for they spread their terror in the land of the living, and have borne their shame with them that descend into the pit: they are laid in the midst of the slain.", "bbe": "They have made a bed for her among the dead, and all her people are round about her resting-place: all of them without circumcision, put to death with the sword; for they were a cause of fear in the land of the living, and are put to shame with those who go down to the underworld: they have been given a place among those who have been put to the sword.", "geneva": "They haue made his bed in the mids of the slaine with al his multitude: their graues are round about him: all these vncircucised are slaine by the sworde: though they haue caused their feare in the land of ye liuing, yet haue they borne their shame with them that goe downe to the pitte: they are laide in the middes of them, that be slaine.", "wycliffe": "In the myddis of slayn men thei puttiden his bed in alle the puplis of hym; his sepulcre is in the cumpas of hym. Alle these weren vncircumcidid and slayn bi swerd, for thei yauen drede in the lond of lyuynge men, and baren her schenschipe with hem that gon doun in to the lake; thei ben set in the myddis of slayn men.", "rotherham": "In the midst of them who were thrust through, have they have placed a couch for her with all her multitude, Round about it, are her graves,-All of them, uncircumcised. Thrust through with the sword. For that their terror was caused in the land of the living. And so they have borne their confusion, with them who descend into the pit, In the midst of them who were thrust through, hath it been placed.", "darby": "They have set him a bed in the midst of the slain, with all his multitude: their graves are round about him, all of them uncircumcised, slain by the sword, though their terror was caused in the land of the living; and they have borne their confusion with them that go down to the pit: he is put in the midst of them that are slain.", "twenty": "", "jps": "They have set her a bed in the midst of the slain with all her multitude; her graves are round about them; all of them uncircumcised, slain by the sword; because their terror was caused in the land of the living, yet have they borne their shame with them that go down to the pit; they are put in the midst of them that are slain.", "acv": "They have set a bed for her in the midst of the slain with all her multitude. Her graves are round about her, all of them uncircumcised, slain by the sword. For their terror was caused in the land of the living, and they have borne their shame with those who go down to the pit. He is put in the midst of those who are slain.", "anderson": "", "haweis": "", "noyes": "Among the slain have they set her a bed with all her multitude; Her graves are round about her, All of them slain, uncircumcised, by the sword. Though they caused terror in the land of the living, Yet they bear their shame with them that have gone down to the pit; They are laid in the midst of the slain.", "webster": "They have set her a bed in the midst of the slain with all her multitude: her graves [are] around him: all of them uncircumcised, slain by the sword: though their terror was caused in the land of the living, yet have they borne their shame with them that go down to the pit: he is put in the midst of [them that are] slain.", "vulgate": "in medio interfectorum posuerunt cubile eius in universis populis eius in circuitu eius sepulchrum illius omnes hii incircumcisi interfectique gladio dederant enim terrorem in terra viventium et portaverunt ignominiam suam cum his qui descendunt in lacum in medio interfectorum positi sunt;", "brenton": "in the midst of the slain."}}, {"v": 26, "ref": "32:26", "o": "שָׁ֣ם מֶ֤שֶׁךְ תֻּבַל֙ וְ/כָל הֲמוֹנָ֔/הּ סְבִֽיבוֹתָ֖י/ו קִבְרוֹתֶ֑י/הָ כֻּלָּ֤/ם עֲרֵלִים֙ מְחֻ֣לְלֵי חֶ֔רֶב כִּֽי נָתְנ֥וּ חִתִּיתָ֖/ם בְּ/אֶ֥רֶץ חַיִּֽים", "en": {"kjv": "There is Meshech, Tubal, and all her multitude: her graves are round about him: all of them uncircumcised, slain by the sword, though they caused their terror in the land of the living.", "web": "There is Meshech, Tubal, and all their multitude; their graves are around them; all of them uncircumcised, slain by the sword; for they caused their terror in the land of the living.", "bsb": "Meshech and Tubal are there with all their multitudes, with their graves all around them. All of them are uncircumcised, slain by the sword, because they spread their terror in the land of the living.", "asv": "There is Meshech, Tubal, and all their multitude; their graves are round about them; all of them uncircumcised, slain by the sword; for they caused their terror in the land of the living.", "ylt": "There is Meshech, Tubal, and all her multitude, Round about him are her graves, All of them uncircumcised, pierced of the sword, For they gave their terror in the land of the living,", "dra": "There is Mosoch, and Thubal, and all their multitude: their graves are round about him: all of them uncircumcised and slain, and fallen by the sword: though they spread their terror in the land of the living.", "bbe": "There is Meshech, Tubal, and all her people, round about her last resting-place: all of them without circumcision, put to death by the sword; for they were a cause of fear in the land of the living.", "geneva": "There is Meshech, Tubal, and all their multitude, their graues are round about them: al these vncircumcised were slaine by the sworde, though they caused their feare to be in ye land of the liuing.", "wycliffe": "There ben Mosoch and Tubal, and al the multitude therof; the sepulcris therof ben in the cumpasse therof. Alle these men vncircumcidid weren slayn, and fallynge doun bi swerd, for thei yauen her drede in the lond of lyuynge men.", "rotherham": "There, are Meshech-Tuba and all her multitude, Round about it, are her graves,— All of them uncircumcised, Who were thrust through with the sword, For that they made themselves a terror in the land of the living;", "darby": "There is Meshech, Tubal, and all their multitude, their graves round about them, all of them uncircumcised, slain by the sword, though they caused their terror in the land of the living.", "twenty": "", "jps": "There is Meshech, Tubal, and all her multitude; her graves are round about them; all of them uncircumcised, slain by the sword; because they caused their terror in the land of the living.", "acv": "There is Meshech, Tubal, and all their multitude. Their graves are round about them, all of them uncircumcised, slain by the sword, for they caused their terror in the land of the living.", "anderson": "", "haweis": "", "noyes": "There is Meshech, Tubal, and all their multitude; Their graves are around them; All of them slain, uncircumcised, by the sword, Though they caused terror in the land of the living.", "webster": "There [is] Meshech, Tubal, and all her multitude: her graves [are] around him: all of them uncircumcised, slain by the sword, though they caused their terror in the land of the living.", "vulgate": "ibi Mosoch et Thubal et omnis multitudo eius in circuitu illius sepulchra eius omnes hii incircumcisi interfectique et cadentes gladio quia dederunt formidinem suam in terra viventium;", "brenton": "There were laid Mosoch, and Thobel, and all his strength round about his tomb: all his slain men, all the uncircumcised, slain with the sword, who caused their fear to be in the land of the living."}}, {"v": 27, "ref": "32:27", "o": "וְ/לֹ֤א יִשְׁכְּבוּ֙ אֶת גִּבּוֹרִ֔ים נֹפְלִ֖ים מֵ/עֲרֵלִ֑ים אֲשֶׁ֣ר יָרְדֽוּ שְׁא֣וֹל בִּ/כְלֵֽי מִלְחַמְתָּ/ם֩ וַ/יִּתְּנ֨וּ אֶת חַרְבוֹתָ֜/ם תַּ֣חַת רָאשֵׁי/הֶ֗ם וַ/תְּהִ֤י עֲוֺֽנֹתָ/ם֙ עַל עַצְמוֹתָ֔/ם כִּֽי חִתִּ֥ית גִּבּוֹרִ֖ים בְּ/אֶ֥רֶץ חַיִּֽים", "en": {"kjv": "And they shall not lie with the mighty that are fallen of the uncircumcised, which are gone down to hell with their weapons of war: and they have laid their swords under their heads, but their iniquities shall be upon their bones, though they were the terror of the mighty in the land of the living.", "web": "They shall not lie with the mighty who are fallen of the uncircumcised, who have gone down to Sheol with their weapons of war, and have laid their swords under their heads, and their iniquities are on their bones; for they were the terror of the mighty in the land of the living.", "bsb": "They do not lie down with the fallen warriors of old, who went down to Sheol with their weapons of war, whose swords were placed under their heads, whose shields rested on their bones, although the terror of the mighty was once in the land of the living.", "asv": "And they shall not lie with the mighty that are fallen of the uncircumcised, that are gone down to Sheol with their weapons of war, and have laid their swords under their heads, and their iniquities are upon their bones; forthey werethe terror of the mighty in the land of the living.", "ylt": "And they lie not with the mighty, Who are falling of the uncircumcised, Who have gone down to sheol with their weapons of war, And they put their swords under their heads, And their iniquities are on their bones, For the terror of the mighty is in the land of the living.", "dra": "And they shall not sleep with the brave, and with them that fell uncircumcised, that went down to hell with their weapons, and laid their swords under their heads, and their iniquities were in their bones, because they were the terror of the mighty in the land of the living.", "bbe": "And they have been put to rest with the fighting men who came to their end in days long past, who went down to the underworld with their instruments of war, placing their swords under their heads, and their body-covers are over their bones; for their strength was a cause of fear in the land of the living.", "geneva": "And they shall not lie with the valiant of the vncircumcised, that are fallen, which are gone down to the graue, with their weapons of warre, and haue laied their swords vnder their heads, but their iniquitie shalbe vpon their bones: because they were the feare of the mighty in the lande of the liuing.", "wycliffe": "And thei schulen not slepe with stronge men, and fallynge doun, and vncircumcidid, that yeden doun in to helle with her armuris, and puttiden her swerdis vndur her heedis. And the wickidnessis of hem weren in the boonys of hem, for thei weren maad the drede of stronge men in the lond of lyuynge men.", "rotherham": "Therefore shall they not lie with the mighty men The fallen ones from age-past times, Who descended into hades with their weapons of war And their swords were placed under their heads. But their iniquities have come upon their bones Because of the terror of the mighty in the land of the living.", "darby": "And they lie not with the mighty, [that are] fallen of the uncircumcised, who are gone down to Sheol with their weapons of war; and whose swords are laid under their heads, and whose iniquities are upon their bones, though they were the terror of the mighty in the land of the living.", "twenty": "", "jps": "And they that are inferior to the uncircumcised shall not lie with the mighty that are gone down to the nether-world with their weapons of war, whose swords are laid under their heads, and whose iniquities are upon their bones; because the terror of the mighty was in the land of the living.", "acv": "And they shall not lie with the mighty who are fallen of the uncircumcised, who have gone down to Sheol with their weapons of war, and have laid their swords under their heads. But their iniquities are upon their bones, for they were the terror of the mighty in the land of the living.", "anderson": "", "haweis": "", "noyes": "Shall they not lie with the mighty of the uncircumcised that are fallen, Who have gone down to the pit with their weapons of war, Having their swords laid under their heads, And their iniquity resting upon their bones, Though they were the terror of the mighty in the land of the living?", "webster": "And they shall not lie with the mighty [that are] fallen of the uncircumcised, who are gone down to the grave, with their weapons of war: and they have laid their swords under their heads, but their iniquities shall be upon their bones, though [they were] the terror of the mighty in the land of the living.", "vulgate": "et non dormient cum fortibus cadentibusque et incircumcisis qui descenderunt ad infernum cum armis suis et posuerunt gladios suos sub capitibus suis et fuerunt iniquitates eorum in ossibus eorum quia terror fortium facti sunt in terra viventium;", "brenton": "And they are laid with the giants that fell of old, who went down to Hades with their weapons of war: and they laid their swords under their heads, but their iniquities were upon their bones, because they terrified all men during their life."}}, {"v": 28, "ref": "32:28", "o": "וְ/אַתָּ֗ה בְּ/ת֧וֹךְ עֲרֵלִ֛ים תִּשָּׁבַ֥ר וְ/תִשְׁכַּ֖ב אֶת חַלְלֵי חָֽרֶב", "en": {"kjv": "Yea, thou shalt be broken in the midst of the uncircumcised, and shalt lie with them that are slain with the sword.", "web": "But you shall be broken in the midst of the uncircumcised, and shall lie with those who are slain by the sword.", "bsb": "But you too will be shattered and lie down among the uncircumcised, with those slain by the sword.", "asv": "But thou shalt be broken in the midst of the uncircumcised, and shalt lie with them that are slain by the sword.", "ylt": "And thou, in the midst of the uncircumcised art broken, And dost lie with the pierced of the sword.", "dra": "So thou also shalt be broken in the midst of the uncircumcised, and shalt sleep with them that are slain by the sword.", "bbe": "But you will have your bed among those without circumcision, and will be put to rest with those who have been put to death with the sword.", "geneva": "Yea, thou shalt be broken in the middes of the vncircumcised, and lie with them that are slaine by the sworde.", "wycliffe": "And thou therfor schalt be al to-foulid in the myddis of vncircumcidid men, and schalt slepe with hem that ben slayn bi swerd.", "rotherham": "Thou, therefore in the midst of the uncircumcised, shalt be overthrown. And shalt lie low with them who were thrust through by the sword.", "darby": "Thou also shalt be broken in the midst of the uncircumcised, and shalt lie with them that are slain with the sword.", "twenty": "", "jps": "But thou, in the midst of the uncircumcised shalt thou be broken and lie, even with them that are slain by the sword.", "acv": "But thou shall be broken in the midst of the uncircumcised, and shall lie with those who are slain by the sword.", "anderson": "", "haweis": "", "noyes": "And thou also shalt be broken in the midst of the uncircumcised, And shalt lie down with them that are slain by the sword.", "webster": "Yes, thou shalt be broken in the midst of the uncircumcised, and shalt lie with [them that are] slain with the sword.", "vulgate": "et tu ergo in medio incircumcisorum contereris et dormies cum interfectis gladio;", "brenton": "And thou shalt lie in the midst of the uncircumcised, with them that have been slain by the sword."}}, {"v": 29, "ref": "32:29", "o": "שָׁ֣מָּ/ה אֱד֗וֹם מְלָכֶ֨י/הָ֙ וְ/כָל נְשִׂיאֶ֔י/הָ אֲשֶׁר נִתְּנ֥וּ בִ/גְבוּרָתָ֖/ם אֶת חַלְלֵי חָ֑רֶב הֵ֛מָּה אֶת עֲרֵלִ֥ים יִשְׁכָּ֖בוּ וְ/אֶת יֹ֥רְדֵי בֽוֹר", "en": {"kjv": "There is Edom, her kings, and all her princes, which with their might are laid by them that were slain by the sword: they shall lie with the uncircumcised, and with them that go down to the pit.", "web": "There is Edom, her kings and all her princes, who in their might are laid with those who are slain by the sword: they shall lie with the uncircumcised, and with those who go down to the pit.", "bsb": "Edom is there, and all her kings and princes, who despite their might are laid among those slain by the sword. They lie down with the uncircumcised, with those who descend to the Pit.", "asv": "There is Edom, her kings and all her princes, who in their might are laid with them that are slain by the sword: they shall lie with the uncircumcised, and with them that go down to the pit.", "ylt": "There is Edom, her kings, and all her princes, Who have been given up in their might, With the pierced of the sword, They with the uncircumcised do lie, And with those going down to the pit.", "dra": "There is Edom, and her kings, and all her princes, who with their army are joined with them that are slain by the sword: and have slept with the uncircumcised, and with them that go down into the pit.", "bbe": "There is Edom, her kings and all her princes, who have been given a resting-place with those who were put to the sword: they will be resting among those without circumcision, even with those who go down to the underworld.", "geneva": "There is Edom, his Kings, and all his princes, which with their strength are laied by them that were slaine by the sworde: they shall sleepe with the vncircumcised, and with them that goe downe to the pit.", "wycliffe": "There is Idumee, and the kingis therof, and alle duykis therof, that ben youun with her oost, with men slayn bi swerd, and which slepten with vncircumcidid men, and with hem that yeden doun in to the lake.", "rotherham": "There, are Edom her kings and all her princes, Who have been delivered up in their might. With them who were thrust through by he sword,— They with the uncircumcised, shall lie low. Even with them who descend into the pit.", "darby": "There is Edom, her kings, and all her princes, who in their might are laid with them that are slain by the sword: they lie with the uncircumcised, and with them that go down to the pit.", "twenty": "", "jps": "There is Edom, her kings and all her princes, who for all their might are laid with them that are slain by the sword; they shall lie with the uncircumcised, and with them that go down to the pit.", "acv": "There is Edom, its kings and all its rulers, who in their might are laid with those who are slain by the sword. They shall lie with the uncircumcised, and with those who go down to the pit.", "anderson": "", "haweis": "", "noyes": "There is Edom, her kings and all her princes, Who in their might are laid with them that are slain by the sword; They lie down with the uncircumcised, With them that have gone down to the pit.", "webster": "There [is] Edom, her kings, and all her princes, who with their might are laid by [them that were] slain by the sword: they shall lie with the uncircumcised, and with them that go down to the pit.", "vulgate": "ibi Idumea et reges eius omnes duces eius qui dati sunt cum exercitu suo cum interfectis gladio et qui cum incircumcisis dormierunt et cum his qui descenderunt in lacum;", "brenton": "There are laid the princes of Assur, who yielded their strength to a wound of the sword: these are laid with the slain, with them that go down to the pit."}}, {"v": 30, "ref": "32:30", "o": "שָׁ֣מָּ/ה נְסִיכֵ֥י צָפ֛וֹן כֻּלָּ֖/ם וְ/כָל צִֽדֹנִ֑י אֲשֶׁר יָרְד֣וּ אֶת חֲלָלִ֗ים בְּ/חִתִּיתָ֤/ם מִ/גְבֽוּרָתָ/ם֙ בּוֹשִׁ֔ים וַ/יִּשְׁכְּב֤וּ עֲרֵלִים֙ אֶת חַלְלֵי חֶ֔רֶב וַ/יִּשְׂא֥וּ כְלִמָּתָ֖/ם אֶת י֥וֹרְדֵי בֽוֹר", "en": {"kjv": "There be the princes of the north, all of them, and all the Zidonians, which are gone down with the slain; with their terror they are ashamed of their might; and they lie uncircumcised with them that be slain by the sword, and bear their shame with them that go down to the pit.", "web": "There are the princes of the north, all of them, and all the Sidonians, who are gone down with the slain; in the terror which they caused by their might they are put to shame; and they lie uncircumcised with those who are slain by the sword, and bear their shame with those who go down to the pit.", "bsb": "All the leaders of the north and all the Sidonians are there; they went down in disgrace with the slain, despite the terror of their might. They lie uncircumcised with those slain by the sword and bear their shame with those who descend to the Pit.", "asv": "There are the princes of the north, all of them, and all the Sidonians, who are gone down with the slain; in the terror which they caused by their might they are put to shame; and they lie uncircumcised with them that are slain by the sword, and bear their shame with them that go down to the pit.", "ylt": "There are princes of the north, All of them, and every Zidonian, Who have gone down with the pierced in their terror, Of their might they are ashamed, And they lie uncircumcised with the pierced of the sword, And they bear their shame with those going down to the pit.", "dra": "There are all the princes of the north, and all the hunters: who were brought down with the slain, fearing, and confounded in their strength: who slept uncircumcised with them that are slain by the sword, and have borne their shame with them that go down into the pit.", "bbe": "There are the chiefs of the north, all of them, and all the Zidonians, who have gone down with those who have been put to the sword: they are shamed on account of all the fear caused by their strength; they are resting there without circumcision, among those who have been put to the sword, and are put to shame with those who go down to the underworld.", "geneva": "There be al the princes of the North, with al the Zidonians, which are gone downe with the slaine, with their feare: they are ashamed of their strength, and the vncircumcised sleepe with them that be slaine by the sword, and beare their shame with them that goe downe to the pit.", "wycliffe": "There ben alle princes of the north, and alle hunteris, that weren led forth with slayn men, that ben dredinge and schent in her strengthe, which slepten vncircumcidid with men slayn bi swerd, and baren her schenschipe with hem that yeden doun in to the lake.", "rotherham": "There, are the princes of the North, all of them, and all the Zidonians, Who have descended with them who were thrust through. By reason of the terror they caused, of their might, are they ashamed, So they have lain down uncircumcised. With them who were thrust through by the sword, And they have bowed their confusion with them who descend into the pit.", "darby": "There are the princes of the north, all of them, and all the Zidonians, that are gone down with the slain — ashamed of the terror which they caused through their might; and they lie uncircumcised with them that are slain by the sword, and bear their confusion with them that go down to the pit.", "twenty": "", "jps": "There are the princes of the north, all of them, and all the Zidonians, who are gone down with the slain, ashamed for all the terror which they caused by their might, and they lie uncircumcised with them that are slain by the sword, and bear their shame with them that go down to the pit.", "acv": "There are the rulers of the north, all of them, and all the Sidonians, who have gone down with the slain. In the terror which they caused by their might they are put to shame. And they lie uncircumcised with those who are slain by the sword, and bear their shame with those who go down to the pit.", "anderson": "", "haweis": "", "noyes": "There are the princes of the North, All of them, and all the Sidonians, Who have gone down to the slain; In the midst of the terror of their might they are put to shame; They lie down uncircumcised with them that are slain by the sword, And bear their shame with them that have gone down to the pit.", "webster": "There [are] the princes of the north, all of them, and all the Zidonians, who are gone down with the slain; with their terror they are ashamed of their might; and they lie uncircumcised with [them that are] slain by the sword, and bear their shame with them that go down to the pit.", "vulgate": "ibi principes aquilonis omnes et universi venatores qui deducti sunt cum interfectis paventes et in sua fortitudine confusi qui dormierunt incircumcisi cum interfectis gladio et portaverunt confusionem suam cum his qui descendunt in lacum;", "brenton": "There are the princes of the north, even all the captains of Assur, who go down slain to Hades: they lie uncircumcised among the slain with the sword together with their terror and their strength, and they have received their punishment with them that go down to the pit."}}, {"v": 31, "ref": "32:31", "o": "אוֹתָ/ם֙ יִרְאֶ֣ה פַרְעֹ֔ה וְ/נִחַ֖ם עַל כָּל המונ/ה הֲמוֹנ֑/וֹ חַלְלֵי חֶ֨רֶב֙ פַּרְעֹ֣ה וְ/כָל חֵיל֔/וֹ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Pharaoh shall see them, and shall be comforted over all his multitude, even Pharaoh and all his army slain by the sword, saith the Lord God.", "web": "Pharaoh shall see them, and shall be comforted over all his multitude, even Pharaoh and all his army, slain by the sword, says the Lord Yahweh.", "bsb": "Pharaoh will see them and be comforted over all his multitude— Pharaoh and all his army, slain by the sword, declares the Lord GOD.", "asv": "Pharaoh shall see them, and shall be comforted over all his multitude, even Pharaoh and all his army, slain by the sword, saith the Lord Jehovah.", "ylt": "Then doth Pharaoh see, And he hath been comforted for all his multitude, The pierced of the sword--Pharaoh and all his force, An affirmation of the Lord Jehovah.", "dra": "Pharao saw them, and he was comforted concerning all his multitude, which was slain by the sword: Pharao, and all his army, saith the Lord God:", "bbe": "Pharaoh will see them and be comforted on account of all his people: even Pharaoh and all his army, put to death by the sword, says the Lord.", "geneva": "Pharaoh shall see them, and hee shall be comforted ouer all his multitude: Pharaoh, and all his armie shall be slaine by the sword, saieth the Lord God.", "wycliffe": "Farao siy hem, and was coumfortid on al his multitude that was slayn bi swerd. And Farao and al his oost, seith the Lord God, baren her schenschipe with hem that yeden doun in to the lake;", "rotherham": "Them, shall Pharaoh see, and be grieved over all his multitude,— Thrust through with the sword, shall be Pharaoh and all his army! Declareth My Lord, Yahweh.", "darby": "Pharaoh shall see them, and shall be comforted over all his multitude, Pharaoh and all his army slain by the sword, saith the Lord Jehovah.", "twenty": "", "jps": "These shall Pharaoh see, and shall be comforted over all his multitude; even Pharaoh and all his army, slain by the sword, saith the L-rd GOD.", "acv": "Pharaoh shall see them, and shall be comforted over all his multitude, even Pharaoh and all his army, slain by the sword, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Pharaoh shall see them, And shall comfort himself over all his multitude; Even Pharaoh and all his army are slain by the sword, Saith the Lord Jehovah.", "webster": "Pharaoh shall see them, and shall be comforted over all his multitude, [even] Pharaoh and all his army slain by the sword, saith the Lord GOD.", "vulgate": "vidit eos Pharao et consolatus est super universa multitudine sua quae interfecta est gladio Pharao et omnis exercitus eius ait Dominus Deus;", "brenton": "King Pharao shall see them, and shall be comforted over all their force, saith the Lord God."}}, {"v": 32, "ref": "32:32", "o": "כִּֽי נָתַ֥תִּי אֶת חתית/ו חִתִּיתִ֖/י בְּ/אֶ֣רֶץ חַיִּ֑ים וְ/הֻשְׁכַּב֩ בְּ/ת֨וֹךְ עֲרֵלִ֜ים אֶת חַלְלֵי חֶ֗רֶב פַּרְעֹה֙ וְ/כָל הֲמוֹנֹ֔/ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "For I have caused my terror in the land of the living: and he shall be laid in the midst of the uncircumcised with them that are slain with the sword, even Pharaoh and all his multitude, saith the Lord God.", "web": "For I have put his terror in the land of the living; and he shall be laid in the midst of the uncircumcised, with those who are slain by the sword, even Pharaoh and all his multitude, says the Lord Yahweh.", "bsb": "For I will spread My terror in the land of the living, so that Pharaoh and all his multitude will be laid to rest among the uncircumcised, with those slain by the sword, declares the Lord GOD.”", "asv": "For I have put his terror in the land of the living; and he shall be laid in the midst of the uncircumcised, with them that are slain by the sword, even Pharaoh and all his multitude, saith the Lord Jehovah.", "ylt": "For I have given his terror in the land of the living, And he hath been laid down in the midst of the uncircumcised, With the pierced of the sword--Pharaoh, and all his multitude, An affirmation of the Lord Jehovah!'", "dra": "Because I have spread my terror in the land of the living, and he hath slept in the midst of the uncircumcised with them that are slain by the sword: Pharao and all his multitude, saith the Lord God.", "bbe": "For he put his fear in the land of the living: and he will be put to rest among those without circumcision, with those who have been put to death with the sword, even Pharaoh and all his people, says the Lord.", "geneva": "For I haue caused my feare to be in the lande of the liuing: and he shall be laid in the mids of the vncircumcised with them, that are slaine by the sword, euen Pharaoh and all his multitude, sayeth the Lord God.", "wycliffe": "for he yaf his drede in the lond of lyuynge men. And Farao and al his multitude slepte in the myddis of vncircumcidid men, with men slayn bi swerd, seith the Lord God.", "rotherham": "For I have suffered his terror to be in the land of the living, Therefore shall be laid low In the midst of the uncircumcised With them who were thrust through by the sword, Pharaoh and all his multitude! Declareth My Lord, Yahweh.", "darby": "For I have caused my terror in the land of the living; and he shall be laid in the midst of the uncircumcised, with them that are slain by the sword, Pharaoh and all his multitude, saith the Lord Jehovah.", "twenty": "", "jps": "For I have put My terror in the land of the living; and he shall be laid in the midst of the uncircumcised, with them that are slain by the sword, even Pharaoh and all his multitude, saith the L-rd GOD.'", "acv": "For I have put his terror in the land of the living, and he shall be laid in the midst of the uncircumcised, with those who are slain by the sword, even Pharaoh and all his multitude, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Though I suffered him to spread terror in the land of the living, Yet is he laid in the midst of the uncircumcised, With them that are slain by the sword, Even Pharaoh and all his multitude, Saith the Lord Jehovah.", "webster": "For I have caused my terror in the land of the living: and he shall be laid in the midst of the uncircumcised with [them that are] slain with the sword, [even] Pharaoh and all his multitude, saith the Lord GOD.", "vulgate": "quia dedi terrorem meum in terra viventium et dormivit in medio incircumcisorum cum interfectis gladio Pharao et omnis multitudo eius ait Dominus Deus;", "brenton": "For I have caused his fear to be upon the land of the living yet he shall lie in the midst of the uncircumcised with them that are slain with the sword, even Pharao, and all his multitude with him, saith the Lord God."}}]}, {"c": 33, "verses": [{"v": 1, "ref": "33:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Again the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Again, the woorde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Again the word of Jehovah came to me, saying:", "webster": "Again the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "33:2", "o": "בֶּן אָדָ֗ם דַּבֵּ֤ר אֶל בְּנֵֽי עַמְּ/ךָ֙ וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם אֶ֕רֶץ כִּֽי אָבִ֥יא עָלֶ֖י/הָ חָ֑רֶב וְ/לָקְח֨וּ עַם הָ/אָ֜רֶץ אִ֤ישׁ אֶחָד֙ מִ/קְצֵי/הֶ֔ם וְ/נָתְנ֥וּ אֹת֛/וֹ לָ/הֶ֖ם לְ/צֹפֶֽה", "en": {"kjv": "Son of man, speak to the children of thy people, and say unto them, When I bring the sword upon a land, if the people of the land take a man of their coasts, and set him for their watchman:", "web": "Son of man, speak to the children of your people, and tell them, When I bring the sword on a land, and the people of the land take a man from among them, and set him for their watchman;", "bsb": "“Son of man, speak to your people and tell them: ‘Suppose I bring the sword against a land, and the people of that land choose a man from among them, appointing him as their watchman,", "asv": "Son of man, speak to the children of thy people, and say unto them, When I bring the sword upon a land, and the people of the land take a man from among them, and set him for their watchman;", "ylt": "`Son of man, speak unto the sons of thy people, and thou hast said unto them: A land--when I bring in against it a sword, And the people of the land have taken one man out of their borders, And made him to them for a watchman.", "dra": "Son of man, speak to the children of thy people, and say to them: When I bring the sword upon a land, if the people of the land take a man, one of their meanest, and make him a watchman over them:", "bbe": "Son of man, give a word to the children of your people, and say to them, When I make the sword come on a land, if the people of the land take a man from among their number and make him their watchman:", "geneva": "Sonne of man, speake to the children of thy people, and say vnto them, When I bring the sworde vpon a lande, if the people of the lande take a man from among them, and make him their watchman,", "wycliffe": "and he seide, Thou, sone of man, speke to the sones of thi puple, and thou schalt seie to hem, A lond whanne Y bringe in a swerd on it, and the puple of the lond takith o man of hise laste men, and makith hym aspiere on hym,", "rotherham": "Son of man Speak unto the sons of thy people and thou shalt say unto them, A land—when I bring upon it a sword, And the people of the land shall take one man out of their whole number, and appoint him for them, as watchman;", "darby": "Son of man, speak to the children of thy people, and say unto them, When I bring the sword upon a land, and the people of the land take one man from among them all, and set him for their watchman:", "twenty": "", "jps": "'Son of man, speak to the children of thy people, and say unto them: When I bring the sword upon a land, if the people of the land take a man from among them, and set him for their watchman;", "acv": "Son of man, speak to the sons of thy people, and say to them, When I bring the sword upon a land, and the people of the land take a man from among them, and set him for their watchman,", "anderson": "", "haweis": "", "noyes": "Son of man, speak to the children of thy people, and say to them, When I bring the sword upon a land, and the people of the land take a man out of their whole number, and set him for their watchman,", "webster": "Son of man, speak to the children of thy people, and say to them, When I bring the sword upon a land, if the people of the land take a man of their borders, and set him for their watchman:", "vulgate": "fili hominis loquere ad filios populi tui et dices ad eos terra cum induxero super eam gladium et tulerit populus terrae virum unum de novissimis suis et constituerit eum super se speculatorem;", "brenton": "Son of man, speak to the children of thy people, and thou shalt say to them, On whatsoever land I shall bring a sword, and the people of the land take one man of them, and set him for their watchman:"}}, {"v": 3, "ref": "33:3", "o": "וְ/רָאָ֥ה אֶת הַ/חֶ֖רֶב בָּאָ֣ה עַל הָ/אָ֑רֶץ וְ/תָקַ֥ע בַּ/שּׁוֹפָ֖ר וְ/הִזְהִ֥יר אֶת הָ/עָֽם", "en": {"kjv": "If when he seeth the sword come upon the land, he blow the trumpet, and warn the people;", "web": "if, when he sees the sword come on the land, he blow the trumpet, and warn the people;", "bsb": "and he sees the sword coming against that land and blows the ram’s horn to warn the people.", "asv": "if, when he seeth the sword come upon the land, he blow the trumpet, and warn the people;", "ylt": "And he hath seen the sword coming against the land, And hath blown with a trumpet, and hath warned the people,", "dra": "And he sees the sword coming upon the land, and sound the trumpet, and tell the people:", "bbe": "If, when he sees the sword coming on the land, by sounding the horn he gives the people news of their danger;", "geneva": "If when hee seeth the sworde come vpon ye land, he blow the trumpet, and warne the people,", "wycliffe": "and he seeth a swerd comynge on the lond, and sowneth with a clarioun, and tellith to the puple,", "rotherham": "And he shall see the sword coming upon the land,—and shall blow with the horn and warn the people", "darby": "if he see the sword coming upon the land, and blow the trumpet, and warn the people;", "twenty": "", "jps": "if, when he seeth the sword come upon the land, he blow the horn, and warn the people;", "acv": "if, when he sees the sword come upon the land, he blows the trumpet, and warns the people,", "anderson": "", "haweis": "", "noyes": "and he seeth the sword coming on the land, and bloweth the trumpet, and warneth the people,", "webster": "If when he seeth the sword come upon the land, he shall blow the trumpet, and warn the people;", "vulgate": "et ille viderit gladium venientem super terram et cecinerit bucina et adnuntiaverit populo;", "brenton": "and he shall see the sword coming upon the land, and blow the trumpet, and sound an alarm to the people;"}}, {"v": 4, "ref": "33:4", "o": "וְ/שָׁמַ֨ע הַ/שֹּׁמֵ֜עַ אֶת ק֤וֹל הַ/שּׁוֹפָר֙ וְ/לֹ֣א נִזְהָ֔ר וַ/תָּ֥בוֹא חֶ֖רֶב וַ/תִּקָּחֵ֑/הוּ דָּמ֥/וֹ בְ/רֹאשׁ֖/וֹ יִֽהְיֶֽה", "en": {"kjv": "Then whosoever heareth the sound of the trumpet, and taketh not warning; if the sword come, and take him away, his blood shall be upon his own head.", "web": "then whoever hears the sound of the trumpet, and doesn’t take warning, if the sword come, and take him away, his blood shall be on his own head.", "bsb": "Then if anyone hears the sound of the horn but fails to heed the warning, and the sword comes and takes him away, his blood will be on his own head.", "asv": "then whosoever heareth the sound of the trumpet, and taketh not warning, if the sword come, and take him away, his blood shall be upon his own head.", "ylt": "And the hearer hath heard the voice of the trumpet, and he hath not taken warning, And come in doth the sword, and taketh him away, His blood is on his head.", "dra": "Then he that heareth the sound of the trumpet, whosoever he be, and doth not look to himself, if the sword come, and cut him off: his blood shall be upon his own head.", "bbe": "Then anyone who, hearing the sound of the horn, does not take note of it, will himself be responsible for his death, if the sword comes and takes him away.", "geneva": "Then hee that heareth the sounde of the trumpet, and will not bee warned, if the sworde come, and take him away, his blood shall be vpon his owne head.", "wycliffe": "forsothe a man that herith, who euer he is, the sowne of the clarioun, and kepith not him silf, and the swerd cometh, and takith hym awei, the blood of hym schal be on the heed of hym.", "rotherham": "Then as for him who really heard the sound of the horn and took not warning, The sword indeed hath come and taken him away,— His blood, upon his own head shall remain:—", "darby": "then whosoever heareth the sound of the trumpet, and taketh not warning, if the sword come and take him away, his blood shall be upon his own head.", "twenty": "", "jps": "then whosoever heareth the sound of the horn, and taketh not warning, if the sword come, and take him away, his blood shall be upon his own head;", "acv": "then whoever hears the sound of the trumpet, and takes no warning, if the sword comes, and takes him away, his blood shall be upon his own head.", "anderson": "", "haweis": "", "noyes": "then whoever heareth the sound of the trumpet, and taketh not warning, and the sword cometh and taketh him away, his blood shall be upon his own head.", "webster": "Then whoever heareth the sound of the trumpet, and taketh not warning; if the sword shall come and take him away, his blood shall be upon his own head.", "vulgate": "audiens autem quisquis ille est sonum bucinae non se observaverit veneritque gladius et tulerit eum sanguis ipsius super caput eius erit;", "brenton": "and he that hears the sound of the trumpet shall hear indeed, and yet not take heed, and the sword shall come upon him, and overtake him, his blood shall be upon his own head."}}, {"v": 5, "ref": "33:5", "o": "אֵת֩ ק֨וֹל הַ/שּׁוֹפָ֤ר שָׁמַע֙ וְ/לֹ֣א נִזְהָ֔ר דָּמ֖/וֹ בּ֣/וֹ יִֽהְיֶ֑ה וְ/ה֥וּא נִזְהָ֖ר נַפְשׁ֥/וֹ מִלֵּֽט", "en": {"kjv": "He heard the sound of the trumpet, and took not warning; his blood shall be upon him. But he that taketh warning shall deliver his soul.", "web": "He heard the sound of the trumpet, and didn’t take warning; his blood shall be on him; whereas if he had taken warning, he would have delivered his soul.", "bsb": "Since he heard the sound of the horn but failed to heed the warning, his blood will be on his own head. If he had heeded the warning, he would have saved his life.", "asv": "He heard the sound of the trumpet, and took not warning; his blood shall be upon him; whereas if he had taken warning, he would have delivered his soul.", "ylt": "The voice of the trumpet he heard, And he hath not taken warning, his blood is on him, And he who took warning his soul hath delivered.", "dra": "He heard the sound of the trumpet, and did not look to himself, his blood shall be upon him: but if he look to himself, he shall save his life.", "bbe": "On hearing the sound of the horn, he did not take note; his blood will be on him; for if he had taken note his life would have been safe.", "geneva": "For he heard the sound of the trumpet, and woulde not bee admonished: therefore his blood shall be vpon him: but he that receiueth warning, shall saue his life.", "wycliffe": "He herde the sown of the clarioun, and kepte not hym silf, his blood schal be in hym; forsothe if he kepith hym silf, he schal saue his lijf.", "rotherham": "The sound of the horn, he heard, but took not warning, His blood, upon himself shall remain,— Whereas had he taken warning, his own soul, he should have delivered.", "darby": "He heard the sound of the trumpet, and took not warning; his blood is upon him: whereas had he taken warning, he would have delivered his soul.", "twenty": "", "jps": "he heard the sound of the horn, and took not warning, his blood shall be upon him; whereas if he had taken warning, he would have delivered his soul.", "acv": "He heard the sound of the trumpet, and took no warning; his blood shall be upon him. Whereas if he had taken warning, he would have delivered his soul.", "anderson": "", "haweis": "", "noyes": "He heard the sound of the trumpet, and took not warning. His blood shall be upon him. But he that taketh warning shall save his life.", "webster": "He heard the sound of the trumpet, and took not warning; his blood shall be upon him. But he that taketh warning shall deliver his soul.", "vulgate": "sonum bucinae audivit et non se observavit sanguis eius in ipso erit si autem custodierit animam suam salvavit;", "brenton": "Because he heard the sound of the trumpet, and took no heed, his blood shall be upon him: but the other, because he took heed, has delivered his soul."}}, {"v": 6, "ref": "33:6", "o": "וְ֠/הַ/צֹּפֶה כִּֽי יִרְאֶ֨ה אֶת הַ/חֶ֜רֶב בָּאָ֗ה וְ/לֹֽא תָקַ֤ע בַּ/שּׁוֹפָר֙ וְ/הָ/עָ֣ם לֹֽא נִזְהָ֔ר וַ/תָּב֣וֹא חֶ֔רֶב וַ/תִּקַּ֥ח מֵ/הֶ֖ם נָ֑פֶשׁ ה֚וּא בַּ/עֲוֺנ֣/וֹ נִלְקָ֔ח וְ/דָמ֖/וֹ מִ/יַּֽד הַ/צֹּפֶ֥ה אֶדְרֹֽשׁ", "en": {"kjv": "But if the watchman see the sword come, and blow not the trumpet, and the people be not warned; if the sword come, and take any person from among them, he is taken away in his iniquity; but his blood will I require at the watchman’s hand.", "web": "But if the watchman sees the sword come, and doesn’t blow the trumpet, and the people aren’t warned, and the sword comes, and take any person from among them; he is taken away in his iniquity, but his blood will I require at the watchman’s hand.", "bsb": "But if the watchman sees the sword coming and fails to blow the horn to warn the people, and the sword comes and takes away a life, then that one will be taken away in his iniquity, but I will hold the watchman accountable for his blood.’", "asv": "But if the watchman see the sword come, and blow not the trumpet, and the people be not warned, and the sword come, and take any person from among them; he is taken away in his iniquity, but his blood will I require at the watchman’s hand.", "ylt": "And the watchman, when he seeth the sword coming in, And he hath not blown with a trumpet, And the people hath not been warned, And come in doth a sword, And taketh away of them--a soul, He in his iniquity is taken away, And his blood from the hand of the watchman I require.", "dra": "And if the watchman see the sword coming, and sound not the trumpet: and the people look not to themselves, and the sword come, and cut off a soul from among them: he indeed is taken away in his iniquity, but I will require his blood at the hand of the watchman.", "bbe": "But if the watchman sees the sword coming, and does not give a note on the horn, and the people have no word of the danger, and the sword comes and takes any person from among them; he will be taken away in his sin, but I will make the watchman responsible for his blood.", "geneva": "But if the watchman see the sworde come, and blowe not the trumpet, and the people be not warned: if the sworde come, and take any person from among them, he is taken away for his iniquitie, but his blood will I require at the watchmans hande.", "wycliffe": "That if the aspiere seeth a swerd comynge, and sowneth not with a clarioun, and the puple kepith not hym silf, and the swerd cometh, and takith awei a man of hem, sotheli he is takun in his wickidnesse; but Y schal seke the blood of hym of the hond of the aspiere.", "rotherham": "But as for the watchman-When he seeth the sword coming. And hath not blown with the horn. And the people, have not been warned, And the sword, hath come and taken away from among them any person he, for his iniquity, hath been taken away, But his blood at the hand of the watchman will I require.", "darby": "But if the watchman see the sword coming, and blow not the trumpet, and the people be not warned, if the sword come and take a person from among them, he is taken away in his iniquity; but his blood will I require at the watchman's hand.", "twenty": "", "jps": "But if the watchman see the sword come, and blow not the horn, and the people be not warned, and the sword do come, and take any person from among them, he is taken away in his iniquity, but his blood will I require at the watchman's hand.", "acv": "But if the watchman sees the sword come, and does not blow the trumpet, and the people are not warned, and the sword comes, and takes any person from among them, he is taken away in his iniquity, but I will require his blood at the watchman's hand.", "anderson": "", "haweis": "", "noyes": "But if the watchman see the sword coming, and blow not the trumpet, and the people be not warned, and the sword come and take away any person from among them, he is taken away for his iniquity, but his blood will I require at the watchman’s hand.", "webster": "But if the watchman shall see the sword come, and blow not the trumpet, and the people be not warned; if the sword shall come, and take [any] person from among them, he is taken away in his iniquity; but his blood will I require at the watchman's hand.", "vulgate": "quod si speculator viderit gladium venientem et non insonuerit bucina et populus non se custodierit veneritque gladius et tulerit de eis animam ille quidem in iniquitate sua captus est sanguinem autem eius de manu speculatoris requiram;", "brenton": "But if the watchman see the sword coming, and do not sound the trumpet, and the people do not watch; and the sword come, and take a soul from among them, that soul is taken because of its iniquity; but the blood thereof will I require at the watchman's hand."}}, {"v": 7, "ref": "33:7", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם צֹפֶ֥ה נְתַתִּ֖י/ךָ לְ/בֵ֣ית יִשְׂרָאֵ֑ל וְ/שָׁמַעְתָּ֤ מִ/פִּ/י֙ דָּבָ֔ר וְ/הִזְהַרְתָּ֥ אֹתָ֖/ם מִמֶּֽ/נִּי", "en": {"kjv": "So thou, O son of man, I have set thee a watchman unto the house of Israel; therefore thou shalt hear the word at my mouth, and warn them from me.", "web": "So you, son of man, I have set you a watchman to the house of Israel; therefore hear the word at my mouth, and give them warning from me.", "bsb": "As for you, O son of man, I have made you a watchman for the house of Israel; so hear the word from My mouth and give them the warning from Me.", "asv": "So thou, son of man, I have set thee a watchman unto the house of Israel; therefore hear the word at my mouth, and give them warning from me.", "ylt": "And thou, son of man, A watchman I gave thee to the house of Israel, And thou hast heard from My mouth a word, And thou hast warned them from Me.", "dra": "So thou, O son of man, I have made thee a watchman to the house of Israel: therefore thou shalt hear the word from my mouth, and shalt tell it them from me.", "bbe": "So you, son of man, I have made you a watchman for the children of Israel; and you are to give ear to the word of my mouth and give them news from me of their danger.", "geneva": "So thou, O sonne of man, I haue made thee a watchman vnto the house of Israel: therefore thou shalt heare the woorde at my mouth, and admonish them from me.", "wycliffe": "And, thou, sone of man, Y yaf thee aspiere to the hous of Israel; therfor thou schalt here of my mouth a word, and schalt telle to hem of me.", "rotherham": "Thou therefore Son of man, A watchman, have I appointed thee, to the house of Israel, So then thou shalt hear at my mouth a message, and shalt warn them from me.", "darby": "So thou, son of man, I have set thee a watchman unto the house of Israel; and thou shalt hear the word from my mouth, and warn them from me.", "twenty": "", "jps": "So thou, son of man, I have set thee a watchman unto the house of Israel; therefore, when thou shalt hear the word at My mouth, warn them from Me.", "acv": "So thou, son of man, I have set thee a watchman to the house of Israel. Therefore hear the word at my mouth, and give them warning from me.", "anderson": "", "haweis": "", "noyes": "So thou, son of man, I have set thee a watchman to the house of Israel, that thou shouldst hear the word from my mouth, and warn them from me.", "webster": "So thou, O son of man, I have set thee a watchman to the house of Israel; therefore thou shalt hear the word at my mouth, and warn them from me.", "vulgate": "et tu fili hominis speculatorem dedi te domui Israhel audiens ergo ex ore meo sermonem adnuntiabis eis ex me;", "brenton": "And thou, son of man, I have set thee as a watchman to the house of Israel, and thou shalt hear a word from my mouth."}}, {"v": 8, "ref": "33:8", "o": "בְּ/אָמְרִ֣/י לָ/רָשָׁ֗ע רָשָׁע֙ מ֣וֹת תָּמ֔וּת וְ/לֹ֣א דִבַּ֔רְתָּ לְ/הַזְהִ֥יר רָשָׁ֖ע מִ/דַּרְכּ֑/וֹ ה֤וּא רָשָׁע֙ בַּ/עֲוֺנ֣/וֹ יָמ֔וּת וְ/דָמ֖/וֹ מִ/יָּדְ/ךָ֥ אֲבַקֵּֽשׁ", "en": {"kjv": "When I say unto the wicked, O wicked man, thou shalt surely die; if thou dost not speak to warn the wicked from his way, that wicked man shall die in his iniquity; but his blood will I require at thine hand.", "web": "When I tell the wicked, O wicked man, you shall surely die, and you don’t speak to warn the wicked from his way; that wicked man shall die in his iniquity, but his blood will I require at your hand.", "bsb": "If I say to the wicked, ‘O wicked man, you will surely die,’ but you do not speak out to dissuade him from his way, then that wicked man will die in his iniquity, yet I will hold you accountable for his blood.", "asv": "When I say unto the wicked, O wicked man, thou shalt surely die, and thou dost not speak to warn the wicked from his way; that wicked man shall die in his iniquity, but his blood will I require at thy hand.", "ylt": "In My saying to the wicked, O wicked one--thou dost surely die, And thou hast not spoken to warn the wicked from his way, He--the wicked--in his iniquity doth die, And his blood from thy hand I require.", "dra": "When I say to the wicked: O wicked man, thou shalt surely die: if thou dost not speak to warn the wicked man from his way: that wicked man shall die in his iniquity, but I will require his blood at thy hand.", "bbe": "When I say to the evil-doer, Death will certainly overtake you; and you say nothing to make clear to the evil-doer the danger of his way; death will overtake that evil man in his evil-doing, but I will make you responsible for his blood.", "geneva": "When I shall say vnto the wicked, O wicked man, thou shalt die the death, if thou doest not speake, and admonish the wicked of his way, that wicked man shall die for his iniquitie, but his blood will I require at thine hand.", "wycliffe": "If whanne Y seie to the wickid man, Thou, wickid man, schalt die bi deth, thou spekist not, that the wickid man kepe hym silf fro his weie, thilke wickid man schal die in his wickidnesse, but Y schal seke his blood of thin hond.", "rotherham": "When I say to the lawless man O lawless man thou shalt surely die, And thou have not spoken to warn the lawless man from his way He the lawless man for his iniquity shall die, But his blood- at thy hand- will I demand.", "darby": "When I say unto the wicked, Wicked [man], thou shalt certainly die; and thou speakest not to warn the wicked from his way, that wicked [man] shall die in his iniquity; but his blood will I require at thy hand.", "twenty": "", "jps": "When I say unto the wicked: O wicked man, thou shalt surely die, and thou dost not speak to warn the wicked from his way; that wicked man shall die in his iniquity, but his blood will I require at thy hand.", "acv": "When I say to the wicked man, O wicked man, thou shall surely die, and thou do not speak to warn the wicked man from his way, that wicked man shall die in his iniquity, but I will require his blood at thy hand.", "anderson": "", "haweis": "", "noyes": "When I say to the wicked, \"O wicked man, thou shalt surely die!\" and thou speakest not to warn the wicked from his way, that wicked man shall die for his iniquity, but his blood will I require at thy hand.", "webster": "When I say to the wicked, O wicked [man], thou shalt surely die; if thou dost not speak to warn the wicked from his way, that wicked [man] shall die in his iniquity; but his blood will I require at thy hand.", "vulgate": "si me dicente ad impium impie morte morieris non fueris locutus ut se custodiat impius a via sua ipse impius in iniquitate sua morietur sanguinem autem eius de manu tua requiram;", "brenton": "When I say to the sinner, Thou shalt surely die; if thou speak not to warn the wicked from his way, the wicked himself shall die in his iniquity; but his blood will I require at thine hand."}}, {"v": 9, "ref": "33:9", "o": "וְ֠/אַתָּה כִּֽי הִזְהַ֨רְתָּ רָשָׁ֤ע מִ/דַּרְכּ/וֹ֙ לָ/שׁ֣וּב מִמֶּ֔/נָּה וְ/לֹא שָׁ֖ב מִ/דַּרְכּ֑/וֹ ה֚וּא בַּ/עֲוֺנ֣/וֹ יָמ֔וּת וְ/אַתָּ֖ה נַפְשְׁ/ךָ֥ הִצַּֽלְתָּ", "en": {"kjv": "Nevertheless, if thou warn the wicked of his way to turn from it; if he do not turn from his way, he shall die in his iniquity; but thou hast delivered thy soul.", "web": "Nevertheless, if you warn the wicked of his way to turn from it, and he doesn’t turn from his way; he shall die in his iniquity, but you have delivered your soul.", "bsb": "But if you warn the wicked man to turn from his way, and he does not turn from it, he will die in his iniquity, but you will have saved your life.", "asv": "Nevertheless, if thou warn the wicked of his way to turn from it, and he turn not from his way; he shall die in his iniquity, but thou hast delivered thy soul.", "ylt": "And thou, when thou hast warned the wicked of his way, to turn back from it, And he hath not turned back from his way, He in his iniquity doth die, And thou thy soul hast delivered.", "dra": "But if thou tell the wicked man, that he may be converted from his ways, and he be not converted from his way he shall die in his iniquity: but thou hast delivered thy soul.", "bbe": "But if you make clear to the evil-doer the danger of his way for the purpose of turning him from it, and he is not turned from his way, death will overtake him in his evil-doing, but your life will be safe.", "geneva": "Neuerthelesse, If thou warne the wicked of his way, to turne from it, if he doe not turne from his way, he shall die for his iniquitie, but thou hast deliuered thy soule.", "wycliffe": "Forsothe if whanne thou tellist to the wickid man, that he be conuertid fro his weies, he is not conuertid fro his weie, he schal die in his wickidnesse; certis thou hast delyuered thi soule.", "rotherham": "But as for thyself When thou hast warned a lawless man from his way, to turn therefrom, And he hath not turned from his way He, for his own iniquity shall die, But thou hast delivered thine own life,", "darby": "But if thou warn the wicked of his way to turn from it, and he do not turn from his way, he shall die in his iniquity; but thou hast delivered thy soul.", "twenty": "", "jps": "Nevertheless, if thou warn the wicked of his way to turn from it, and he turn not from his way; he shall die in his iniquity, but thou hast delivered thy soul.", "acv": "Nevertheless, if thou warn the wicked man of his way to turn from it, and he does not turn from his way, he shall die in his iniquity, but thou have delivered thy soul.", "anderson": "", "haweis": "", "noyes": "Yet if thou warn the wicked of his way, to turn from it, and he turneth not from his way, he shall die for his iniquity, but thou hast delivered thyself.", "webster": "Nevertheless, if thou shalt warn the wicked of his way to turn from it; if he shall not turn from his way, he shall die in his iniquity; but thou hast delivered thy soul.", "vulgate": "si autem adnuntiante te ad impium ut a viis suis convertatur non fuerit conversus a via sua ipse in iniquitate sua morietur porro tu animam tuam liberasti;", "brenton": "But if thou forewarn the wicked of his way to turn from it, and he turn not from his way, he shall die in his ungodliness; but thou hast delivered thine own soul."}}, {"v": 10, "ref": "33:10", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם אֱמֹר֙ אֶל בֵּ֣ית יִשְׂרָאֵ֔ל כֵּ֤ן אֲמַרְתֶּם֙ לֵ/אמֹ֔ר כִּֽי פְשָׁעֵ֥י/נוּ וְ/חַטֹּאתֵ֖י/נוּ עָלֵ֑י/נוּ וּ/בָ֛/ם אֲנַ֥חְנוּ נְמַקִּ֖ים וְ/אֵ֥יךְ נִֽחְיֶֽה", "en": {"kjv": "Therefore, O thou son of man, speak unto the house of Israel; Thus ye speak, saying, If our transgressions and our sins be upon us, and we pine away in them, how should we then live?", "web": "You, son of man, tell the house of Israel: Thus you speak, saying, Our transgressions and our sins are on us, and we pine away in them; how then can we live?", "bsb": "Now as for you, son of man, tell the house of Israel that this is what they have said: ‘Our transgressions and our sins are heavy upon us, and we are wasting away because of them! How can we live?’", "asv": "And thou, son of man, say unto the house of Israel: Thus ye speak, saying, Our transgressions and our sins are upon us, and we pine away in them; how then can we live?", "ylt": "And thou, son of man, say unto the house of Israel: Rightly ye have spoken, saying: Surely our transgressions and our sins are on us, And in them we are wasting away, How, then, do we live?", "dra": "Thou therefore, O son of man, say to the house of Israel: Thus you have spoken, saying: Our iniquities, and our sins are upon us, and we pine away in them: how then can we live?", "bbe": "And you, son of man, say to the children of Israel, You say, Our wrongdoing and our sins are on us and we are wasting away in them; how then may we have life?", "geneva": "Therefore, O thou sonne of man, speake vnto the house of Israel, Thus yee speake and say, If our transgressions and our sinnes bee vpon vs, and we are consumed because of them, howe should we then liue?", "wycliffe": "Therfore thou, sone of man, seie to the hous of Israel, Thus ye spaken, seiynge, Oure wickidnessis and oure synnes ben on vs, and we failen in tho; hou therfor moun we lyue? seie thou to hem,", "rotherham": "Thou, therefore, Son of man, Say unto the house of Israel, Thus, have ye spoken saying: When our transgressions and our sins are upon us,—and for them, we are melting away How then can we live?", "darby": "And thou, son of man, say unto the house of Israel, Thus ye speak, saying, Our transgressions and our sins are upon us, and we waste away in them, how then should we live?", "twenty": "", "jps": "Therefore, O thou son of man, say unto the house of Israel: Thus ye speak, saying: Our transgressions and our sins are upon us, and we pine away in them; how then can we live?", "acv": "And thou, son of man, say to the house of Israel, Thus ye speak, saying, Our transgressions and our sins are upon us, and we pine away in them. How then can we live?", "anderson": "", "haweis": "", "noyes": "Thou, therefore, O son of man, say to the house of Israel: Rightly do ye say, \"Our transgressions and our sins are upon us, and through them we pine away. How then can we live?\"", "webster": "Therefore, O thou son of man, speak to the house of Israel; Thus ye speak, saying, If our transgressions and our sins [are] upon us, and we pine away in them, how should we then live?", "vulgate": "tu ergo fili hominis dic ad domum Israhel sic locuti estis dicentes iniquitates nostrae et peccata nostra super nos sunt et in ipsis nos tabescimus quomodo ergo vivere poterimus;", "brenton": "And thou, son of man, say to the house of Israel; Thus have ye spoken, saying, Our errors, and our iniquities weigh upon us, and we pine away in them, and how then shall we live?"}}, {"v": 11, "ref": "33:11", "o": "אֱמֹ֨ר אֲלֵי/הֶ֜ם חַי אָ֣נִי נְאֻ֣ם אֲדֹנָ֣/י יְהוִ֗ה אִם אֶחְפֹּץ֙ בְּ/מ֣וֹת הָ/רָשָׁ֔ע כִּ֣י אִם בְּ/שׁ֥וּב רָשָׁ֛ע מִ/דַּרְכּ֖/וֹ וְ/חָיָ֑ה שׁ֣וּבוּ שׁ֜וּבוּ מִ/דַּרְכֵי/כֶ֧ם הָ/רָעִ֛ים וְ/לָ֥/מָּה תָמ֖וּתוּ בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Say unto them, As I live, saith the Lord God, I have no pleasure in the death of the wicked; but that the wicked turn from his way and live: turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?", "web": "Tell them, As I live, says the Lord Yahweh, I have no pleasure in the death of the wicked; but that the wicked turn from his way and live: turn, turn from your evil ways; for why will you die, house of Israel?", "bsb": "Say to them: ‘As surely as I live, declares the Lord GOD, I take no pleasure in the death of the wicked, but rather that the wicked should turn from their ways and live. Turn! Turn from your evil ways! For why should you die, O house of Israel?’", "asv": "Say unto them, As I live, saith the Lord Jehovah, I have no pleasure in the death of the wicked; but that the wicked turn from his way and live: turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?", "ylt": "Say unto them, I live--an affirmation of the Lord Jehovah, I delight not in the death of the wicked, But--in the turning of the wicked from his way, And he hath lived, Turn back, turn back, from your evil ways, Yea, why do ye die, O house of Israel?", "dra": "Say to them: As I live, saith the Lord God, I desire not the death of the wicked, but that the wicked turn from his way, and live. Turn ye, turn ye from your evil ways: and why will you die, O house of Israel?", "bbe": "Say to them, By my life, says the Lord, I have no pleasure in the death of the evil-doer; it is more pleasing to me if he is turned from his way and has life: be turned, be turned from your evil ways; why are you looking for death, O children of Israel?", "geneva": "Say vnto them, As I liue, sayeth the Lord God, I desire not the death of the wicked, but that the wicked turne from his way and liue: turne you, turne you from your euill waies, for why will ye die, O ye house of Israel?", "wycliffe": "Y lyue, seith the Lord God, Y nyle the deth of the wickid man, but that the wickid man be conuertid fro his weie, and lyue; be ye conuertid fro youre worste weies, and whi schulen ye die, the hous of Israel?", "rotherham": "Say unto them, As I live, Declareth My Lord Yahweh, Surely, I can take no pleasure in the death of the lawless man, But that the lawless man turn from his way, and live,- Turn ye, turn ye, from your wicked ways, For wherefore should ye die. O house of Israel?", "darby": "Say unto them, As I live, saith the Lord Jehovah, I have no pleasure in the death of the wicked; but that the wicked turn from his way and live. Turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?", "twenty": "", "jps": "Say unto them: As I live, saith the L-rd GOD, I have no pleasure in the death of the wicked, but that the wicked turn from his way and live; turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?", "acv": "Say to them, As I live, says the lord Jehovah, I have no pleasure in the death of the wicked man, but that the wicked man turn from his way and live. Turn ye, turn ye from your evil ways, for why will ye die, O house of Israel?", "anderson": "", "haweis": "", "noyes": "Say to them, As I live, saith the Lord Jehovah, I have no pleasure in the death of the wicked, but that the wicked turn from his way and live; turn ye, turn ye, from your evil ways! for why will ye die, O house of Israel?", "webster": "Say to them, [As] I live, saith the Lord GOD, I have no pleasure in the death of the wicked; but that the wicked should turn from his way and live: turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?", "vulgate": "dic ad eos vivo ego dicit Dominus Deus nolo mortem impii sed ut revertatur impius a via sua et vivat convertimini a viis vestris pessimis et quare moriemini domus Israhel;", "brenton": "Say to them, Thus saith the Lord; As I live, I desire not the death of the ungodly, as that the ungodly should turn from his way and live: turn ye heartily from your way; for why will ye die, O house of Israel?"}}, {"v": 12, "ref": "33:12", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם אֱמֹ֤ר אֶל בְּנֵֽי עַמְּ/ךָ֙ צִדְקַ֣ת הַ/צַּדִּ֗יק לֹ֤א תַצִּילֶ֨/נּוּ֙ בְּ/י֣וֹם פִּשְׁע֔/וֹ וְ/רִשְׁעַ֤ת הָֽ/רָשָׁע֙ לֹֽא יִכָּ֣שֶׁל בָּ֔/הּ בְּ/י֖וֹם שׁוּב֣/וֹ מֵֽ/רִשְׁע֑/וֹ וְ/צַדִּ֗יק לֹ֥א יוּכַ֛ל לִֽ/חְי֥וֹת בָּ֖/הּ בְּ/י֥וֹם חֲטֹאתֽ/וֹ", "en": {"kjv": "Therefore, thou son of man, say unto the children of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression: as for the wickedness of the wicked, he shall not fall thereby in the day that he turneth from his wickedness; neither shall the righteous be able to live for his righteousness in the day that he sinneth.", "web": "You, son of man, tell the children of your people, The righteousness of the righteous shall not deliver him in the day of his disobedience; and as for the wickedness of the wicked, he shall not fall thereby in the day that he turns from his wickedness; neither shall he who is righteous be able to live thereby in the day that he sins.", "bsb": "Therefore, son of man, say to your people: ‘The righteousness of the righteous man will not deliver him in the day of his transgression; neither will the wickedness of the wicked man cause him to stumble on the day he turns from his wickedness. Nor will the righteous man be able to survive by his righteousness on the day he sins.’", "asv": "And thou, son of man, say unto the children of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression; and as for the wickedness of the wicked, he shall not fall thereby in the day that he turneth from his wickedness; neither shall he that is righteous be able to live thereby in the day that he sinneth.", "ylt": "And thou, son of man, say unto the sons of thy people: The righteousness of the righteous doth not deliver him in the day of his transgression, And the wickedness of the wicked, He doth not stumble for it in the day of his turning from his wickedness, And the righteous is not able to live in it in the day of his sinning.", "dra": "Thou therefore, O son of man, say to the children of thy people: The justice of the just shall not deliver him, in what day soever he shall sin: and the wickedness of the wicked shall not hurt him, in what day soever he shall turn from his wickedness: and the just shall not be able to live in his justice, in what day soever he shall sin.", "bbe": "And you, son of man, say to the children of your people, The righteousness of the upright man will not make him safe in the day when he does wrong; and the evil-doing of the evil man will not be the cause of his fall in the day when he is turned from his evil-doing; and the upright man will not have life because of his righteousness in the day when he does evil.", "geneva": "Therefore thou sonne of man, saye vnto the children of thy people, The righteousnesse of the righteous shall not deliuer him in the day of his transgression, nor the wickednesse of the wicked shall cause him to fall therein, in the day that he returneth from his wickednesse, neither shall the righteous liue for his righteousnesse in the day that he sinneth.", "wycliffe": "Therfor thou, sone of man, seie to the sones of thi puple, The riytfulnesse of a riytful man schal not delyuere hym, in whateuer dai he doith synne; and the wickidnesse of a wickid man schal not anoye him, in what euere dai he is conuertid fro his wickidnesse; and a iust man schal not mowe lyue in his riytfulnesse, in what euer dai he doith synne.", "rotherham": "Thou, therefore, Son of man Say unto the sons of thy people— The righteousness of the righteous man, shall not deliver him in the day of his transgression, And as for the lawlessness of the lawless man, He shall not stumble thereby, in the day of his return from his lawlessness,- Nor shall the righteous man be able to live thereby, in the day of his sin.", "darby": "And thou, son of man, say unto the children of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression; and as for the wickedness of the wicked, he shall not fall thereby in the day that he turneth from his wickedness; neither shall the righteous be able to live thereby in the day that he sinneth.", "twenty": "", "jps": "And thou, son of man, say unto the children of thy people: The righteousness of the righteous shall not deliver him in the day of his transgression; and as for the wickedness of the wicked, he shall not stumble thereby in the day that he turneth from his wickedness; neither shall he that is righteous be able to live thereby in the day that he sinneth.", "acv": "And thou, son of man, say to the sons of thy people, The righteousness of the righteous man shall not deliver him in the day of his transgression. And as for the wickedness of the wicked man, he shall not fall by it in the day that he turns from his wickedness, nor shall he who is righteous be able to live by it in the day that he sins.", "anderson": "", "haweis": "", "noyes": "Thou also, son of man, say to the sons of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression; and through his wickedness shall not the wicked man fall in the day when he turneth from his wickedness; neither shall the righteous be able to live in the day when he sinneth.", "webster": "Therefore, thou son of man, say to the children of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression: as for the wickedness of the wicked, he shall not fall by it in the day that he turneth from his wickedness; neither shall the righteous be able to live for his [righteousness] in the day that he sinneth.", "vulgate": "tu itaque fili hominis dic ad filios populi tui iustitia iusti non liberabit eum in quacumque die peccaverit et impietas impii non nocebit ei in quacumque die conversus fuerit ab impietate sua et iustus non poterit vivere in iustitia sua in quacumque die peccaverit;", "brenton": "Say to the children of thy people, The righteousness of the righteous shall not deliver him, in the day wherein he errs: and the iniquity of the ungodly shall not harm him, in the day wherein he turns from his iniquity, but the righteous erring shall not be able to deliver himself."}}, {"v": 13, "ref": "33:13", "o": "בְּ/אָמְרִ֤/י לַ/צַּדִּיק֙ חָיֹ֣ה יִֽחְיֶ֔ה וְ/הֽוּא בָטַ֥ח עַל צִדְקָת֖/וֹ וְ/עָ֣שָׂה עָ֑וֶל כָּל צדקת/ו צִדְקֹתָי/ו֙ לֹ֣א תִזָּכַ֔רְנָה וּ/בְ/עַוְל֥/וֹ אֲשֶׁר עָשָׂ֖ה בּ֥/וֹ יָמֽוּת", "en": {"kjv": "When I shall say to the righteous, that he shall surely live; if he trust to his own righteousness, and commit iniquity, all his righteousnesses shall not be remembered; but for his iniquity that he hath committed, he shall die for it.", "web": "When I tell the righteous, that he shall surely live; if he trust to his righteousness, and commit iniquity, none of his righteous deeds shall be remembered; but in his iniquity that he has committed, therein shall he die.", "bsb": "If I tell the righteous man that he will surely live, but he then trusts in his righteousness and commits iniquity, then none of his righteous works will be remembered; he will die because of the iniquity he has committed.", "asv": "When I say to the righteous, that he shall surely live; if he trust to his righteousness, and commit iniquity, none of his righteous deeds shall be remembered; but in his iniquity that he hath committed, therein shall he die.", "ylt": "In My saying of the righteous: He surely liveth, And--he hath trusted on his righteousness, And he hath done perversity, All his righteous acts are not remembered, And for his perversity that he hath done, For it he doth die.", "dra": "Yea, if I shall say to the just that he shall surely live, and he, trusting in his justice, commit iniquity: all his justices shall be forgotten, and his iniquity, which he hath committed, in the same shall he die.", "bbe": "When I say to the upright that life will certainly be his; if he puts his faith in his righteousness and does evil, not one of his upright acts will be kept in memory; but in the evil he has done, death will overtake him.", "geneva": "When I shall say vnto the righteous, that he shall surely liue, if he trust to his owne righteousnes, and commit iniquitie, all his righteousnes shall be no more remembred, but for his iniquitie that he hath committed, he shall die for the same.", "wycliffe": "Also if Y seie to a iust man, that he schal lyue bi lijf, and he tristith in his riytfulnesse, and doith wickidnesse, alle his riytfulnessis schulen be youun to foryetyng, and in his wickidnesse which he wrouyte, in that he schal die.", "rotherham": "When I say of the righteous man He shall surely live but he hath trusted in his righteousness and committed perversity None of his righteous deeds shall be mentioned, But by his perversity which he hath committed—thereby, shall he die.", "darby": "When I say to the righteous that he shall certainly live, and he trusteth to his righteousness and doeth what is wrong, none of his righteous acts shall be remembered; but in his unrighteousness which he hath done, in it shall he die.", "twenty": "", "jps": "When I say to the righteous, that he shall surely live; if he trust to his righteousness, and commit iniquity, none of his righteous deeds shall be remembered; but for his iniquity that he hath committed, for it shall he die.", "acv": "When I say to the righteous man, that he shall surely live, if he trusts his righteousness, and commits iniquity, none of his righteous deeds shall be remembered, but in his iniquity that he has committed, in it he shall die.", "anderson": "", "haweis": "", "noyes": "When I say concerning the righteous, \"He shall surely live,\" and he trusteth in his righteousness, and doeth iniquity, all his righteousness shall not be remembered, but for his iniquity which he hath committed shall he die.", "webster": "When I shall say to the righteous, [that] he shall surely live; if he shall trust to his own righteousness, and commit iniquity, all his righteousnesses shall not be remembered; but for his iniquity that he hath committed, he shall die for it.", "vulgate": "etiam si dixero iusto quod vita vivat et confisus in iustitia sua fecerit iniquitatem omnes iustitiae eius oblivioni tradentur et in iniquitate sua quam operatus est in ipsa morietur;", "brenton": "When I say to the righteous, Thou shalt live; and he trusts in his righteousness, and shall commit iniquity, none of his righteousnesses shall be remembered; in his unrighteousness which he has wrought, in it shall he die."}}, {"v": 14, "ref": "33:14", "o": "וּ/בְ/אָמְרִ֥/י לָֽ/רָשָׁ֖ע מ֣וֹת תָּמ֑וּת וְ/שָׁב֙ מֵֽ/חַטָּאת֔/וֹ וְ/עָשָׂ֥ה מִשְׁפָּ֖ט וּ/צְדָקָֽה", "en": {"kjv": "Again, when I say unto the wicked, Thou shalt surely die; if he turn from his sin, and do that which is lawful and right;", "web": "Again, when I say to the wicked, You shall surely die; if he turn from his sin, and do that which is lawful and right;", "bsb": "But if I tell the wicked man, ‘You will surely die,’ and he turns from his sin and does what is just and right—", "asv": "Again, when I say unto the wicked, Thou shalt surely die; if he turn from his sin, and do that which is lawful and right;", "ylt": "And in My saying to the wicked: Thou surely diest, And--he hath turned back from his sin, And hath done judgment and righteousness,", "dra": "And it I shall say to the wicked: Thou shalt surely die: and he do penance for his sin, and do judgment and justice,", "bbe": "And when I say to the evil-doer, Death will certainly be your fate; if he is turned from his sin and does what is ordered and right;", "geneva": "Againe when I shall say vnto the wicked, thou shalt die the death, if he turne from his sinne, and doe that which is lawfull and right,", "wycliffe": "Forsothe if Y seie to the wickid man, Thou schalt die bi deth, and he doith penaunce for his synne, and doith dom and riytfulnesse,", "rotherham": "And when I say to the lawless man Thou shalt surely die, but he shall turn from his sin, and do justice and righteousness:", "darby": "And when I say unto the wicked, Thou shalt certainly die, and he turneth from his sin, and doeth judgment and justice;", "twenty": "", "jps": "Again, when I say unto the wicked: Thou shalt surely die; if he turn from his sin, and do that which is lawful and right;", "acv": "Again, when I say to the wicked man, Thou shall surely die, if he turns from his sin, and does that which is lawful and right,", "anderson": "", "haweis": "", "noyes": "Again, when I say concerning the wicked, \"He shall surely die,\" and he turneth from his sin, and doeth that which is just and right,", "webster": "Again, when I say to the wicked, Thou shalt surely die; if he shall turn from his sin, and do that which is lawful and right;", "vulgate": "sin autem dixero impio morte morieris et egerit paenitentiam a peccato suo feceritque iudicium et iustitiam;", "brenton": "And when I say to the ungodly, Thou shalt surely die; and he shall turn from his sin, and do judgment and justice,"}}, {"v": 15, "ref": "33:15", "o": "חֲבֹ֨ל יָשִׁ֤יב רָשָׁע֙ גְּזֵלָ֣ה יְשַׁלֵּ֔ם בְּ/חֻקּ֤וֹת הַֽ/חַיִּים֙ הָלַ֔ךְ לְ/בִלְתִּ֖י עֲשׂ֣וֹת עָ֑וֶל חָי֥וֹ יִֽחְיֶ֖ה לֹ֥א יָמֽוּת", "en": {"kjv": "If the wicked restore the pledge, give again that he had robbed, walk in the statutes of life, without committing iniquity; he shall surely live, he shall not die.", "web": "if the wicked restore the pledge, give again that which he had taken by robbery, walk in the statutes of life, committing no iniquity; he shall surely live, he shall not die.", "bsb": "if he restores a pledge, makes restitution for what he has stolen, and walks in the statutes of life without practicing iniquity—then he will surely live; he will not die.", "asv": "if the wicked restore the pledge, give again that which he had taken by robbery, walk in the statutes of life, committing no iniquity; he shall surely live, he shall not die.", "ylt": "(The pledge the wicked restoreth, plunder he repayeth,) In the statutes of life he hath walked, So as not to do perversity, He surely liveth--he doth not die.", "dra": "And if that wicked man restore the pledge, and render what he had robbed, and walk in the commandments of life, and do no unjust thing: he shall surely live, and shall not die.", "bbe": "If the evil-doer lets one who is in his debt have back what is his, and gives back what he had taken by force, and is guided by the rules of life, doing no evil; life will certainly be his, death will not overtake him.", "geneva": "To wit, if the wicked restore the pledge, and giue againe that he had robbed, and walke in the statutes of life, without committing iniquitie, he shall surely liue, and not die.", "wycliffe": "and if thilke wickid man restorith a wed, and yeldith raueyn, and goith in comaundementis of lijf, and doith not ony vniust thing, he schal lyue bi lijf, and schal not die.", "rotherham": "The debt-pledge, the lawless man shall restore Plunder, shall pay back, In the statutes of life, hath walked, so as not to commit perversity. He shall surely live he shall not die:—", "darby": "if the wicked restore the pledge, give again that he had taken by robbery, walk in the statutes of life, doing nothing that is wrong; he shall certainly live, he shall not die.", "twenty": "", "jps": "if the wicked restore the pledge, give back that which he had taken by robbery, walk in the statutes of life, committing no iniquity; he shall surely live, he shall not die.", "acv": "if the wicked man restores the pledge, gives again that which he had taken by robbery, walks in the statutes of life, committing no iniquity, he shall surely live; he shall not die.", "anderson": "", "haweis": "", "noyes": "and the wicked restoreth the pledge, giveth back that which he hath taken by violence, and walketh in the statutes of life without committing iniquity, he shall surely live, he shall not die.", "webster": "[If] the wicked shall restore the pledge, give again that which he had robbed, walk in the statutes of life, without committing iniquity; he shall surely live, he shall not die.", "vulgate": "pignus restituerit ille impius rapinamque reddiderit in mandatis vitae ambulaverit nec fecerit quicquam iniustum vita vivet et non morietur;", "brenton": "and return the pledge, and repay that which he has robbed, and walk in the ordinances of life, so as to do no wrong; he shall surely live, and shall not die."}}, {"v": 16, "ref": "33:16", "o": "כָּל חטאת/ו חַטֹּאתָי/ו֙ אֲשֶׁ֣ר חָטָ֔א לֹ֥א תִזָּכַ֖רְנָה ל֑/וֹ מִשְׁפָּ֧ט וּ/צְדָקָ֛ה עָשָׂ֖ה חָי֥וֹ יִֽחְיֶֽה", "en": {"kjv": "None of his sins that he hath committed shall be mentioned unto him: he hath done that which is lawful and right; he shall surely live.", "web": "None of his sins that he has committed shall be remembered against him: he has done that which is lawful and right; he shall surely live.", "bsb": "None of the sins he has committed will be held against him. He has done what is just and right; he will surely live.", "asv": "None of his sins that he hath committed shall be remembered against him: he hath done that which is lawful and right; he shall surely live.", "ylt": "None of his sin that he hath sinned is remembered to him, Judgment and righteousness he hath done, He doth surely live.", "dra": "None of his sins, which he hath committed, shall be imputed to him: he hath done judgment and justice, he shall surely live.", "bbe": "Not one of the sins which he has done will be kept in mind against him: he has done what is ordered and right, life will certainly be his.", "geneva": "None of his sinnes that he hath comitted, shall be mentioned vnto him: because he hath done that, which is lawful, and right, he shall surely liue.", "wycliffe": "Alle hise synnes which he synnede, schulen not be arettid to hym; he dide doom and riytfulnesse, he schal lyue bi lijf.", "rotherham": "None of his sins which he hath committed shall be called to mind against him,— Justice and righteousness, hath he done He shall surely live.", "darby": "None of his sins which he hath committed shall be remembered against him: he hath done judgment and justice; he shall certainly live.", "twenty": "", "jps": "None of his sins that he hath committed shall be remembered against him; he hath done that which is lawful and right; he shall surely live.", "acv": "None of his sins that he has committed shall be remembered against him. He has done that which is lawful and right; he shall surely live.", "anderson": "", "haweis": "", "noyes": "None of his sins which he hath committed shall be mentioned to him; he hath done that which is just and right; he shall surely live.", "webster": "None of his sins that he hath committed shall be mentioned to him: he hath done that which is lawful and right; he shall surely live.", "vulgate": "omnia peccata eius quae peccavit non inputabuntur ei iudicium et iustitiam fecit vita vivet;", "brenton": "None of his sins which he has committed shall be remembered: because he has wrought judgment and righteousness; by them shall he live."}}, {"v": 17, "ref": "33:17", "o": "וְ/אָמְרוּ֙ בְּנֵ֣י עַמְּ/ךָ֔ לֹ֥א יִתָּכֵ֖ן דֶּ֣רֶךְ אֲדֹנָ֑/י וְ/הֵ֖מָּה דַּרְכָּ֥/ם לֹֽא יִתָּכֵֽן", "en": {"kjv": "Yet the children of thy people say, The way of the Lord is not equal: but as for them, their way is not equal.", "web": "Yet the children of your people say, The way of the Lord is not equal: but as for them, their way is not equal.", "bsb": "Yet your people say, ‘The way of the Lord is not just.’ But it is their way that is not just.", "asv": "Yet the children of thy people say, The way of the Lord is not equal: but as for them, their way is not equal.", "ylt": "And the sons of thy people have said: The way of the Lord is not pondered, As to them--their way is not pondered.", "dra": "And the children of thy people have said: The way of the Lord is not equitable: whereas their own way is unjust.", "bbe": "But the children of your people say, The way of the Lord is not equal: when it is they whose way is not equal.", "geneva": "Yet the children of thy people say, The way of the Lord is not equall: but their owne way is vnequall.", "wycliffe": "And the sones of thi puple seiden, The weie of the Lord is not euene weiyte; and the weie of hem is vniust.", "rotherham": "And can the sons of thy people say, The way of The Lord will not be equal? Nay! but as for them, their way will not be equal!", "darby": "Yet the children of thy people say, The way of the Lord is not equal: but as for them, their way is not equal.", "twenty": "", "jps": "Yet the children of thy people say: The way of the L-rd is not equal; but as for them, their way is not equal.", "acv": "Yet the sons of thy people say, The way of the Lord is not equitable. But as for them, their way is not equitable.", "anderson": "", "haweis": "", "noyes": "And yet the sons of thy people say, \"The way of the Lord is not right!\" But it is their way which is not right.", "webster": "Yet the children of thy people say, The way of the Lord is not equal: but as for them, their way is not equal.", "vulgate": "et dixerunt filii populi tui non est aequi ponderis via Domini et ipsorum via iniusta est;", "brenton": "Yet the children of thy people will say, The way of the Lord is not straight: whereas this their way is not straight."}}, {"v": 18, "ref": "33:18", "o": "בְּ/שׁוּב צַדִּ֥יק מִ/צִּדְקָת֖/וֹ וְ/עָ֣שָׂה עָ֑וֶל וּ/מֵ֖ת בָּ/הֶֽם", "en": {"kjv": "When the righteous turneth from his righteousness, and committeth iniquity, he shall even die thereby.", "web": "When the righteous turns from his righteousness, and commits iniquity, he shall even die therein.", "bsb": "If a righteous man turns from his righteousness and commits iniquity, he will die for it.", "asv": "When the righteous turneth from his righteousness, and committeth iniquity, he shall even die therein.", "ylt": "In the turning back of the righteous from his righteousness, And he hath done perversity--he dieth for it.", "dra": "For when the just shall depart from his justice, and commit iniquities, he shall die in them.", "bbe": "When the upright man, turning away from his righteousness, does evil, death will overtake him in it.", "geneva": "When the righteous turneth from his righteousnesse, and committeth iniquitie, he shall euen die thereby.", "wycliffe": "For whanne a iust man goith awei fro his riytfulnesse, and doith wickidnessis, he schal die in tho;", "rotherham": "When the righteous man shall turn from his righteousness and commit perversity Then shall he die for them;", "darby": "When the righteous turneth from his righteousness, and doeth what is wrong, then he shall die therein.", "twenty": "", "jps": "When the righteous turneth from his righteousness, and committeth iniquity, he shall even die thereby.", "acv": "When the righteous man turns from his righteousness, and commits iniquity, he shall even die in it.", "anderson": "", "haweis": "", "noyes": "When the righteous man turneth from his righteousness, and committeth iniquity, he dieth because of it.", "webster": "When the righteous turneth from his righteousness, and committeth iniquity, for that he shall even die.", "vulgate": "cum enim recesserit iustus a iustitia sua feceritque iniquitatem morietur in eis;", "brenton": "When the righteous turns away from his righteousness, and shall commit iniquities, then shall he die in them."}}, {"v": 19, "ref": "33:19", "o": "וּ/בְ/שׁ֤וּב רָשָׁע֙ מֵֽ/רִשְׁעָת֔/וֹ וְ/עָשָׂ֥ה מִשְׁפָּ֖ט וּ/צְדָקָ֑ה עֲלֵי/הֶ֖ם ה֥וּא יִֽחְיֶֽה", "en": {"kjv": "But if the wicked turn from his wickedness, and do that which is lawful and right, he shall live thereby.", "web": "When the wicked turns from his wickedness, and does that which is lawful and right, he shall live thereby.", "bsb": "But if a wicked man turns from his wickedness and does what is just and right, he will live because of this.", "asv": "And when the wicked turneth from his wickedness, and doeth that which is lawful and right, he shall live thereby.", "ylt": "And in the turning back of the wicked from his wickedness, And he hath done judgment and righteousness, by them he liveth.", "dra": "And when the wicked shall depart from his wickedness, and shall do judgments, and justice, he shall live in them.", "bbe": "And when the evil man, turning away from his evil-doing, does what is ordered and right, he will get life by it.", "geneva": "But if the wicked returne from his wickednesse, and doe that which is lawfull and right, hee shall liue thereby.", "wycliffe": "and whanne a wickid man goith awei fro his wickidnesse, and doith dom and riytfulnes, he schal lyue in tho.", "rotherham": "But when the lawless man shall turn from his lawlessness, and do justice and righteousness Upon them, shall he live.", "darby": "And when the wicked turneth from his wickedness, and doeth judgment and justice, he shall live for these things.", "twenty": "", "jps": "And when the wicked turneth from his wickedness, and doeth that which is lawful and right, he shall live thereby.", "acv": "And when the wicked man turns from his wickedness, and does that which is lawful and right, he shall live thereby.", "anderson": "", "haweis": "", "noyes": "And when the wicked turneth from his wickedness, and doeth that which is just and right, he shall live thereby.", "webster": "But if the wicked shall turn from his wickedness, and do that which is lawful and right, for that he shall live.", "vulgate": "et cum recesserit impius ab impietate sua feceritque iudicium et iustitiam vivet in eis;", "brenton": "And when the sinner turns from his iniquity, and shall do judgment and righteousness, he shall live by them."}}, {"v": 20, "ref": "33:20", "o": "וַ/אֲמַרְתֶּ֕ם לֹ֥א יִתָּכֵ֖ן דֶּ֣רֶךְ אֲדֹנָ֑/י אִ֧ישׁ כִּ/דְרָכָ֛י/ו אֶשְׁפּ֥וֹט אֶתְ/כֶ֖ם בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Yet ye say, The way of the Lord is not equal. O ye house of Israel, I will judge you every one after his ways.", "web": "Yet you say, The way of the Lord is not equal. House of Israel, I will judge every one of you after his ways.", "bsb": "Yet you say, ‘The way of the Lord is not just.’ But I will judge each of you according to his ways, O house of Israel.”", "asv": "Yet ye say, The way of the Lord is not equal. O house of Israel, I will judge you every one after his ways.", "ylt": "And ye have said: The way of the Lord is not pondered, Each according to his ways do I judge you, O house of Israel.'", "dra": "And you say: The way of the Lord is not right, I will judge every one of you according to his ways, O house of Israel.", "bbe": "And still you say, The way of the Lord is not equal. O children of Israel, I will be your judge, giving to everyone the reward of his ways.", "geneva": "Yet yee say, The way of the Lord is not equall. O ye house of Israel, I will iudge you euery one after his waies.", "wycliffe": "And ye seien, The weie of the Lord is not riytful. Y schal deme ech man bi hise weies of you, the hous of Israel.", "rotherham": "And can ye then say, The way of The Lord will not be equal? Every man—according to his own ways so will I judge you O house of Israel?", "darby": "Yet ye say, The way of the Lord is not equal. O house of Israel, I will judge you every one after his ways.", "twenty": "", "jps": "Yet ye say: The way of the L-rd is not equal. O house of Israel, I will judge you every one after his ways.'", "acv": "Yet ye say, The way of the Lord is not equitable. O house of Israel, I will judge you everyone according to his ways.", "anderson": "", "haweis": "", "noyes": "And yet ye say, \"The way of the Lord is not right!\" O house of Israel, I will judge you every one according to his ways!", "webster": "Yet ye say, The way of the Lord is not equal. O ye house of Israel, I will judge you every one after his ways.", "vulgate": "et dicitis non est recta via Domini unumquemque iuxta vias suas iudicabo de vobis domus Israhel;", "brenton": "And this is that which ye said, The way of the Lord is not straight. I will judge you, O house of Israel, every one for his ways."}}, {"v": 21, "ref": "33:21", "o": "וַ/יְהִ֞י בִּ/שְׁתֵּ֧י עֶשְׂרֵ֣ה שָׁנָ֗ה בָּ/עֲשִׂרִ֛י בַּ/חֲמִשָּׁ֥ה לַ/חֹ֖דֶשׁ לְ/גָלוּתֵ֑/נוּ בָּא אֵלַ֨/י הַ/פָּלִ֧יט מִ/ירוּשָׁלִַ֛ם לֵ/אמֹ֖ר הֻכְּתָ֥ה הָ/עִֽיר", "en": {"kjv": "And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that one that had escaped out of Jerusalem came unto me, saying, The city is smitten.", "web": "In the twelfth year of our captivity, in the tenth month, in the fifth day of the month, one who had escaped out of Jerusalem came to me, saying, The city has been struck.", "bsb": "In the twelfth year of our exile, on the fifth day of the tenth month, a fugitive from Jerusalem came to me and reported, “The city has been taken!”", "asv": "And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that one that had escaped out of Jerusalem came unto me, saying, The city is smitten.", "ylt": "And it cometh to pass, in the twelfth year--in the tenth month , in the fifth of the month--of our removal, come in unto me doth one who is escaped from Jerusalem, saying, `The city hath been smitten.'", "dra": "And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that there came to me one that was fled from Jerusalem, saying: The city is laid waste.", "bbe": "Now in the twelfth year after we had been taken away prisoners, in the tenth month, on the fifth day of the month, one who had got away in flight from Jerusalem came to me, saying, The town has been taken.", "geneva": "Also in the twelfth yere of our captiuitie, in the tenth moneth, and in the fift day of the moneth, one that had escaped out of Ierusalem, came vnto me, and said, The citie is smitten.", "wycliffe": "And it was doon in the tweluethe yeer, in the tenthe monethe, in the fyuethe dai of the monethe of our passyng ouer, he that fledde fro Jerusalem cam to me, and seide, The citee is distried.", "rotherham": "And it came to pass in the twelfth year, in the tenth month on the fifth of the month of our exile, that there came unto me one that had escaped out of Jerusalem saying. Smitten is the city!", "darby": "And it came to pass in the twelfth year of our captivity, in the tenth [month], on the fifth of the month, that one who had escaped out of Jerusalem came unto me, saying, The city is smitten!", "twenty": "", "jps": "And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that one that had escaped out of Jerusalem came unto me, saying: 'The city is smitten.'", "acv": "And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that a man who had escaped out of Jerusalem came to me, saying, The city is smitten.", "anderson": "", "haweis": "", "noyes": "And it came to pass in the twelfth year of our captivity, in the tenth month, on the fifth day of the month, that one who had escaped from Jerusalem came to me, saying, \"The city is smitten!\"", "webster": "And it came to pass in the twelfth year of our captivity, in the tenth [month], in the fifth [day] of the month, [that] one that had escaped out of Jerusalem came to me, saying, The city is smitten.", "vulgate": "et factum est in duodecimo anno in duodecimo mense in quinta mensis transmigrationis nostrae venit ad me qui fugerat de Hierusalem dicens vastata est civitas;", "brenton": "And it came to pass in the tenth year of our captivity, in the twelfth month, on the fifth day of the month, that one that had escaped from Jerusalem came to me, saying, The city is taken."}}, {"v": 22, "ref": "33:22", "o": "וְ/יַד יְהוָה֩ הָיְתָ֨ה אֵלַ֜/י בָּ/עֶ֗רֶב לִ/פְנֵי֙ בּ֣וֹא הַ/פָּלִ֔יט וַ/יִּפְתַּ֣ח אֶת פִּ֔/י עַד בּ֥וֹא אֵלַ֖/י בַּ/בֹּ֑קֶר וַ/יִּפָּ֣תַח פִּ֔/י וְ/לֹ֥א נֶאֱלַ֖מְתִּי עֽוֹד", "en": {"kjv": "Now the hand of the Lord was upon me in the evening, afore he that was escaped came; and had opened my mouth, until he came to me in the morning; and my mouth was opened, and I was no more dumb.", "web": "Now the hand of Yahweh had been on me in the evening, before he who was escaped came; and he had opened my mouth, until he came to me in the morning; and my mouth was opened, and I was no more mute.", "bsb": "Now the evening before the fugitive arrived, the hand of the LORD was upon me, and He opened my mouth before the man came to me in the morning. So my mouth was opened and I was no longer mute.", "asv": "Now the hand of Jehovah had been upon me in the evening, before he that was escaped came; and he had opened my mouth, until he came to me in the morning; and my mouth was opened, and I was no more dumb.", "ylt": "And the hand of Jehovah hath been unto me in the evening, before the coming in of the escaped one, and He openeth my mouth till the coming in unto me in the morning, and opened is my mouth, and I have not been silent again.", "dra": "And the hand of the Lord had been upon me in the evening, before he that was fled came: and he opened my mouth till he came to me in the morning, and my mouth being opened, I was silent no more.", "bbe": "Now the hand of the Lord had been on me in the evening, before the man who had got away came to me; and he made my mouth open, ready for his coming to me in the morning; and my mouth was open and I was no longer without voice.", "geneva": "Now the hand of the Lord had bene vpon me in ye euening afore hee that had escaped, came, and had opened my mouth vntill he came to me in the morning: and when hee had opened my mouth, I was no more dumme.", "wycliffe": "Forsothe the hond of the Lord was maad to me in the euentid, bifore that he cam that fledde, and he openyde my mouth, til he cam to me eerli; and whanne my mouth was openyd, Y was no more stille.", "rotherham": "Now the hand of Yahweh, had come unto me in the evening, before the coming of him who had escaped, and he had opened my mouth, by the time that he came to me in the morning, —so my mouth, was opened, and I was dumb no longer.", "darby": "Now the hand of Jehovah had been upon me in the evening, before he that had escaped came; and he had opened my mouth against his coming to me in the morning; and my mouth was opened, and I was no more dumb.", "twenty": "", "jps": "Now the hand of HaShem had been upon me in the evening, before he that was escaped came; and He had opened my mouth against his coming to me in the morning; and my mouth was opened, and I was no more dumb.", "acv": "Now the hand of Jehovah had been upon me in the evening, before he who escaped came. And he had opened my mouth until he came to me in the morning. And my mouth was opened, and I was no more mute.", "anderson": "", "haweis": "", "noyes": "Now the hand of Jehovah had been upon me in the evening before he that had escaped came; and he opened my mouth, until he came to me in the morning; he opened my mouth, so that I was no longer dumb.", "webster": "Now the hand of the LORD was upon me in the evening, before he that had escaped came; and had opened my mouth, until he came to me in the morning; and my mouth was opened, and I was no more dumb.", "vulgate": "manus autem Domini facta fuerat ad me vespere antequam veniret qui fugerat aperuitque os meum donec veniret ad me mane et aperto ore meo non silui amplius;", "brenton": "Now the hand of the Lord had come upon me in the evening, before he came; and he opened my mouth, when he came to me in the morning: and my mouth was open, it was no longer kept closed."}}, {"v": 23, "ref": "33:23", "o": "וַ/יְהִ֥י דְבַר יְהֹוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Then the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "Againe the worde of the Lord came vnto me, and saide,", "wycliffe": "And the word of the Lord was maad to me, and he seide,", "rotherham": "Then came the word of Yahweh unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Then the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "Then the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 24, "ref": "33:24", "o": "בֶּן אָדָ֗ם יֹ֠שְׁבֵי הֶ/חֳרָב֨וֹת הָ/אֵ֜לֶּה עַל אַדְמַ֤ת יִשְׂרָאֵל֙ אֹמְרִ֣ים לֵ/אמֹ֔ר אֶחָד֙ הָיָ֣ה אַבְרָהָ֔ם וַ/יִּירַ֖שׁ אֶת הָ/אָ֑רֶץ וַ/אֲנַ֣חְנוּ רַבִּ֔ים לָ֛/נוּ נִתְּנָ֥ה הָ/אָ֖רֶץ לְ/מוֹרָשָֽׁה", "en": {"kjv": "Son of man, they that inhabit those wastes of the land of Israel speak, saying, Abraham was one, and he inherited the land: but we are many; the land is given us for inheritance.", "web": "Son of man, they who inhabit those waste places in the land of Israel speak, saying, Abraham was one, and he inherited the land: but we are many; the land is given us for inheritance.", "bsb": "“Son of man, those living in the ruins in the land of Israel are saying, ‘Abraham was only one man, yet he possessed the land. But we are many; surely the land has been given to us as a possession.’", "asv": "Son of man, they that inhabit those waste places in the land of Israel speak, saying, Abraham was one, and he inherited the land: but we are many; the land is given us for inheritance.", "ylt": "`Son of man, the inhabitants of these wastes on the ground of Israel are speaking, saying: Alone hath been Abraham--and he possesseth the land, and we are many--to us hath the land been given for a possession.", "dra": "Son of man, they that dwell in these ruinous places in the land of Israel, speak, saying: Abraham was one, and he inherited the land, but we are many, the land is given us in possession.", "bbe": "Son of man, those who are living in these waste places in the land of Israel say, Abraham was but one, and he had land for his heritage: but we are a great number; the land is given to us for our heritage.", "geneva": "Sonne of man, these that dwel in the desolate places of the land of Israel, talke and say, Abraham was but one, and hee possessed the lande: but we are many, therefore the lande shall be giuen vs in possession.", "wycliffe": "Thou, sone of man, thei that dwellen in `thingis in poynt to falle doun on the erthe of Israel, seien, spekynge, Abraham was oon, and bi eritage he hadde the lond in possessioun; forsothe we ben manye, the lond is youun to vs in to possessioun.", "rotherham": "Son of man These inhabitants of waste places on the soil of Israel are saying thus, One, was Abraham. Yet he inherited the land,- But, we, are many, To us, is the land given as an inheritance.", "darby": "Son of man, they that inhabit those waste places in the land of Israel speak, saying, Abraham was one, and he inherited this land, and we are many: the land is given us for a possession.", "twenty": "", "jps": "'Son of man, they that inhabit those waste places in the land of Israel speak, saying: Abraham was one, and he inherited the land; but we are many; the land is given us for inheritance.", "acv": "Son of man, those who inhabit those waste places in the land of Israel speak, saying, Abraham was one, and he inherited the land, but we are many; the land is given us for inheritance.", "anderson": "", "haweis": "", "noyes": "Son of man, they that inhabit those wastes in the land of Israel say, \"Abraham was but one, and he inherited the land; but we are many; to us is the land given for an inheritance.\"", "webster": "Son of man, they that inhabit those wastes of the land of Israel speak, saying, Abraham was one, and he inherited the land: but we [are] many; the land is given to us for inheritance.", "vulgate": "fili hominis qui habitant in ruinosis his super humum Israhel loquentes aiunt unus erat Abraham et hereditate possedit terram nos autem multi nobis data est terra in possessionem;", "brenton": "Son of man, they that inhabit the desolate places on the land of Israel say, Abram was one, and he possessed the land: and we are more numerous; to us the land is given for a possession."}}, {"v": 25, "ref": "33:25", "o": "לָ/כֵן֩ אֱמֹ֨ר אֲלֵי/הֶ֜ם כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה עַל הַ/דָּ֧ם תֹּאכֵ֛לוּ וְ/עֵינֵ/כֶ֛ם תִּשְׂא֥וּ אֶל גִּלּוּלֵי/כֶ֖ם וְ/דָ֣ם תִּשְׁפֹּ֑כוּ וְ/הָ/אָ֖רֶץ תִּירָֽשׁוּ", "en": {"kjv": "Wherefore say unto them, Thus saith the Lord God; Ye eat with the blood, and lift up your eyes toward your idols, and shed blood: and shall ye possess the land?", "web": "Therefore tell them, Thus says the Lord Yahweh: You eat with the blood, and lift up your eyes to your idols, and shed blood: and shall you possess the land?", "bsb": "Therefore tell them that this is what the Lord GOD says: ‘You eat meat with the blood in it, lift up your eyes to your idols, and shed blood. Should you then possess the land?", "asv": "Wherefore say unto them, Thus saith the Lord Jehovah: Ye eat with the blood, and lift up your eyes unto your idols, and shed blood: and shall ye possess the land?", "ylt": "Therefore say unto them: Thus said the Lord Jehovah: With the blood ye do eat, And your eyes ye lift up unto your idols, And blood ye shed, and the land ye inherit!", "dra": "Therefore say to them: Thus saith the Lord God: You that eat with the blood and lift up your eyes to your uncleannesses, and that shed blood: shall you possess the land by inheritance?", "bbe": "For this cause say to them, This is what the Lord has said: You take your meat with the blood, your eyes are lifted up to your images, and you are takers of life: are you to have the land for your heritage?", "geneva": "Wherefore say vnto them, Thus saieth the Lord God, Ye eate with the blood, and lift vp your eyes towarde your idoles, and sheade blood: should ye then possesse the land?", "wycliffe": "Therfor thou schalt seie to hem, The Lord God seith these thingis, Whether ye that eten in blood, and reisen youre iyen to youre vnclennessis, and scheden blood, schulen haue in possessioun the lond bi eritage?", "rotherham": "Wherefore say unto them Thus, saith My Lord. Yahweh. -With the blood, ye do eat. And your eyes, ye do lift up unto your manufactured gods. And blood, ye do shed; And the land, shall ye inherit?", "darby": "Therefore say unto them, Thus saith the Lord Jehovah: Ye eat with the blood, and lift up your eyes toward your idols, and shed blood; and shall ye possess the land?", "twenty": "", "jps": "Wherefore say unto them: Thus saith the L-rd GOD. Ye eat with the blood, and lift up your eyes unto your idols, and shed blood; and shall ye possess the land?", "acv": "Therefore say to them, Thus says the lord Jehovah: Ye eat with the blood, and lift up your eyes to your idols, and shed blood. And shall ye possess the land?", "anderson": "", "haweis": "", "noyes": "Therefore say to them, Thus saith the Lord Jehovah: Ye eat with the blood, and life up your eyes to your idols, and shed blood; and shall ye possess the land?", "webster": "Wherefore say to them, Thus saith the Lord GOD; Ye eat with the blood, and lift up your eyes towards your idols, and shed blood: and shall ye possess the land?", "vulgate": "idcirco dices ad eos haec dicit Dominus Deus qui in sanguine comeditis et oculos vestros levatis ad inmunditias vestras et sanguinem funditis numquid terram hereditate possidebitis;", "brenton": ""}}, {"v": 26, "ref": "33:26", "o": "עֲמַדְתֶּ֤ם עַֽל חַרְבְּ/כֶם֙ עֲשִׂיתֶ֣ן תּוֹעֵבָ֔ה וְ/אִ֛ישׁ אֶת אֵ֥שֶׁת רֵעֵ֖/הוּ טִמֵּאתֶ֑ם וְ/הָ/אָ֖רֶץ תִּירָֽשׁוּ", "en": {"kjv": "Ye stand upon your sword, ye work abomination, and ye defile every one his neighbour’s wife: and shall ye possess the land?", "web": "You stand on your sword, you work abomination, and every one of you defiles his neighbor’s wife: and shall you possess the land?", "bsb": "You have relied on your swords, you have committed detestable acts, and each of you has defiled his neighbor’s wife. Should you then possess the land?’", "asv": "Ye stand upon your sword, ye work abomination, and ye defile every one his neighbor’s wife: and shall ye possess the land?", "ylt": "Ye have stood on your sword, Ye have done abomination, Each the wife of his neighbour ye have defiled, And the land ye possess!", "dra": "You stood on your swords, you have committed abominations, and every one hath defiled his neighbours wife; and shall you possess the land by inheritance?", "bbe": "You put your faith in your swords, you do disgusting things, everyone takes his neighbour's wife: are you to have the land for your heritage?", "geneva": "Ye leane vpon your swordes: ye worke abomination, and yee defile euery one his neighbours wife: should ye then possesse the land?", "wycliffe": "Ye stoden in youre swerdis, ye diden youre abhomynaciouns, and ech man defoulide the wijf of his neiybore; and schulen ye welde the lond bi eritage?", "rotherham": "Ye men have taken your stand by your sword. Ye women have wrought abomination, And every man—with the wife of his neighbour, have ye defiled yourselves; And the land, shall ye inherit?", "darby": "Ye stand upon your sword, ye work abomination, and ye defile every one his neighbour's wife; and shall ye possess the land?", "twenty": "", "jps": "Ye stand upon your sword, ye work abomination, and ye defile every one his neighbour's wife; and shall ye possess the land?", "acv": "Ye stand upon your sword, ye work abomination, and ye defile every man his neighbor's wife. And shall ye possess the land?", "anderson": "", "haweis": "", "noyes": "Ye trust to your swords, ye commit abomination, and ye defile, every one, his neighbor’s wife; and shall ye possess the land?", "webster": "Ye stand upon your sword, ye work abomination, and ye defile every one his neighbor's wife: and shall ye possess the land?", "vulgate": "stetistis in gladiis vestris fecistis abominationes et unusquisque uxorem proximi sui polluit et terram hereditate possidebitis;", "brenton": ""}}, {"v": 27, "ref": "33:27", "o": "כֹּֽה תֹאמַ֨ר אֲלֵ/הֶ֜ם כֹּה אָמַ֨ר אֲדֹנָ֣/י יְהוִה֮ חַי אָנִי֒ אִם לֹ֞א אֲשֶׁ֤ר בֶּֽ/חֳרָבוֹת֙ בַּ/חֶ֣רֶב יִפֹּ֔לוּ וַֽ/אֲשֶׁר֙ עַל פְּנֵ֣י הַ/שָּׂדֶ֔ה לַ/חַיָּ֥ה נְתַתִּ֖י/ו לְ/אָכְל֑/וֹ וַ/אֲשֶׁ֛ר בַּ/מְּצָד֥וֹת וּ/בַ/מְּעָר֖וֹת בַּ/דֶּ֥בֶר יָמֽוּתוּ", "en": {"kjv": "Say thou thus unto them, Thus saith the Lord God; As I live, surely they that are in the wastes shall fall by the sword, and him that is in the open field will I give to the beasts to be devoured, and they that be in the forts and in the caves shall die of the pestilence.", "web": "You shall tell them, Thus says the Lord Yahweh: As I live, surely those who are in the waste places shall fall by the sword; and him who is in the open field will I give to the animals to be devoured; and those who are in the strongholds and in the caves shall die of the pestilence.", "bsb": "Tell them that this is what the Lord GOD says: ‘As surely as I live, those in the ruins will fall by the sword, those in the open field I will give to be devoured by wild animals, and those in the strongholds and caves will die by plague.", "asv": "Thus shalt thou say unto them, Thus saith the Lord Jehovah: As I live, surely they that are in the waste places shall fall by the sword; and him that is in the open field will I give to the beasts to be devoured; and they that are in the strongholds and in the caves shall die of the pestilence.", "ylt": "Thus dost thou say unto them: Thus said the Lord Jehovah: I live--do not they who are in the wastes by the sword fall? And they who are on the face of the field, To the beast I have given for food, And they who are in strongholds and in caves by pestilence die.", "dra": "Say thou thus to them: Thus saith the Lord God: As I live, they that dwell in the ruinous places, shall fall by the sword: and he that is in the field, shall be given to the beasts to be devoured: and they that are in holds, and caves, shall die of the pestilence.", "bbe": "This is what you are to say to them: The Lord has said, By my life, truly, those who are in the waste places will be put to the sword, and him who is in the open field I will give to the beasts for their food, and those who are in the strong places and in holes in the rocks will come to their death by disease.", "geneva": "Say thus vnto them, Thus saieth the Lord God, As I liue, so surely they that are in the desolate places, shall fall by the sword: and him that is in the open field, will I giue vnto the beasts to be deuoured: and they that be in the forts and in the caues, shall die of the pestilence.", "wycliffe": "Thou schalt seie these thingis to hem, Thus seith the Lord God, Y lyue, for thei that dwellen in `thingis redi to falle doun, schulen falle doun bi swerd, and he that is in the feld, schal be youun to beestis to be deuourid; but thei that ben in stronge holdis and in dennes, schulen die bi pestilence.", "rotherham": "Thus shalt thou say unto them, Thus saith My Lord Yahweh, As I live, surely, they who are in the waste places by the sword, shall fall, And him who is on the face of the field to the wild beast, have I given to be devoured,- And they who are in the mountain holds and in the pits :by pestilence, shall die;", "darby": "Say thou thus unto them, Thus saith the Lord Jehovah: [As] I live, verily they that are in the waste places shall fall by the sword, and him that is in the open field will I give to the beasts to be devoured, and they that are in the strongholds and in the caves shall die of the pestilence.", "twenty": "", "jps": "Thus shalt thou say unto them: Thus saith the L-rd GOD: As I live, surely they that are in the waste places shall fall by the sword, and him that is in the open field will I give to the beasts to be devoured, and they that are in the strongholds and in the caves shall die of the pestilence.", "acv": "Thus shall thou say to them. Thus says the lord Jehovah: As I live, surely those who are in the waste places shall fall by the sword, and he who is in the open field I will give to the beasts to be devoured, and those who are in the strongholds and in the caves shall die of the pestilence.", "anderson": "", "haweis": "", "noyes": "Say thou thus to them: Thus saith the Lord Jehovah: As I live, surely they that are in the wastes shall fall by the sword, and him that is in the open country will I give to the beasts to be devoured, and they that are in the forts and caves shall fall by the pestilence.", "webster": "Say thou thus to them, Thus saith the Lord GOD; [As] I live, surely they that [are] in the wastes shall fall by the sword, and him that [is] in the open field will I give to the beasts to be devoured, and they that [are] in the forts and in the caves shall die by the pestilence.", "vulgate": "haec dices ad eos sic dicit Dominus Deus vivo ego quia qui in ruinosis habitant gladio cadent et qui in agro est bestiis tradetur ad devorandum qui autem in praesidiis et in speluncis sunt peste morientur;", "brenton": "Therefore say to them, Thus saith the Lord God, As I live, surely they that are in the desolate places shall fall by swords and they that are in the open plain shall be given for food to the wild beasts of the field, and them that are in the fortified cities and them that are in the caves I will slay with pestilence."}}, {"v": 28, "ref": "33:28", "o": "וְ/נָתַתִּ֤י אֶת הָ/אָ֨רֶץ֙ שְׁמָמָ֣ה וּ/מְשַׁמָּ֔ה וְ/נִשְׁבַּ֖ת גְּא֣וֹן עֻזָּ֑/הּ וְ/שָֽׁמְמ֛וּ הָרֵ֥י יִשְׂרָאֵ֖ל מֵ/אֵ֥ין עוֹבֵֽר", "en": {"kjv": "For I will lay the land most desolate, and the pomp of her strength shall cease; and the mountains of Israel shall be desolate, that none shall pass through.", "web": "I will make the land a desolation and an astonishment; and the pride of her power shall cease; and the mountains of Israel shall be desolate, so that no one shall pass through.", "bsb": "I will make the land a desolate waste, and the pride of her strength will come to an end. The mountains of Israel will become desolate, so that no one will pass through.", "asv": "And I will make the land a desolation and an astonishment; and the pride of her power shall cease; and the mountains of Israel shall be desolate, so that none shall pass through.", "ylt": "And I have made the land a desolation and an astonishment, And ceased hath the excellency of its strength, And desolated have been mountains of Israel, Without any one passing through.", "dra": "And I will make the land a wilderness, and a desert, and the proud strength thereof shall fail, and the mountains of Israel shall be desolate, because there is none to pass by them,", "bbe": "And I will make the land a waste and a cause of wonder, and the pride of her strength will come to an end; and the mountains of Israel will be made waste so that no one will go through.", "geneva": "For I will lay the land desolate and waste, and the pompe of her strength shall cease: and the moutaines of Israel shalbe desolate, and none shall passe through.", "wycliffe": "And Y schal yyue the lond in to wildirnesse, and in to desert, and the pryde and strengthe therof schal faile; and the hillis of Israel schulen be maad desolat, for noon is that schal passe bi tho.", "rotherham": "And I will make the land a desolation and an astonishment, So shall be made to cease the pride of her strength,- And the mountains of Israel shall be too desolate for any to pass through.", "darby": "And I will make the land a desolation and an astonishment, and the pride of her strength shall cease; and the mountains of Israel shall be desolated, so that none shall pass through.", "twenty": "", "jps": "And I will make the land most desolate, and the pride of her power shall cease; and the mountains of Israel shall be desolate, so that none shall pass through.", "acv": "And I will make the land a desolation and an astonishment. And the pride of her power shall cease. And the mountains of Israel shall be desolate, so that none shall pass through.", "anderson": "", "haweis": "", "noyes": "And I will make the land an utter desolation; and the pride of her strength shall cease; and the mountains of Israel shall be desolate, so that none shall pass through.", "webster": "For I will lay the land most desolate, and the pomp of her strength shall cease; and the mountains of Israel shall be desolate, that none shall pass through.", "vulgate": "et dabo terram in solitudinem et desertum et deficiet superba fortitudo eius et desolabuntur montes Israhel eo quod nullus sit qui per eos transeat;", "brenton": "And I will make the land desert, and the pride of her strength shall perish; and the mountains of Israel shall be made desolate by reason of no man passing through."}}, {"v": 29, "ref": "33:29", "o": "וְ/יָדְע֖וּ כִּֽי אֲנִ֣י יְהוָ֑ה בְּ/תִתִּ֤/י אֶת הָ/אָ֨רֶץ֙ שְׁמָמָ֣ה וּ/מְשַׁמָּ֔ה עַ֥ל כָּל תּוֹעֲבֹתָ֖/ם אֲשֶׁ֥ר עָשֽׂוּ", "en": {"kjv": "Then shall they know that I am the Lord, when I have laid the land most desolate because of all their abominations which they have committed.", "web": "Then shall they know that I am Yahweh, when I have made the land a desolation and an astonishment, because of all their abominations which they have committed.", "bsb": "Then they will know that I am the LORD, when I have made the land a desolate waste because of all the abominations they have committed.’", "asv": "Then shall they know that I am Jehovah, when I have made the land a desolation and an astonishment, because of all their abominations which they have committed.", "ylt": "And they have known that I am Jehovah, In My making the land a desolation and an astonishment, For all their abominations that they have done.", "dra": "And they shall know that I am the Lord, when I shall have made their land waste and desolate, for all their abominations which they have committed.", "bbe": "Then they will be certain that I am the Lord, when I have made the land a waste and a cause of wonder, because of all the disgusting things which they have done,", "geneva": "Then shall they know that I am the Lord, when I haue laid ye land desolate and wast, because of al their abominations, that they haue committed.", "wycliffe": "And thei schulen wite, that Y am the Lord, whanne Y schal yyue her lond desolat and desert, for alle her abhomynaciouns whiche thei wrouyten.", "rotherham": "So shall they know that I, am Yahweh,— When I make the land a desolation and an astonishment, because of all their abominations which they have committed.", "darby": "And they shall know that I [am] Jehovah, when I have made the land a desolation and an astonishment because of all their abominations which they have committed.", "twenty": "", "jps": "Then shall they know that I am HaShem, when I have made the land most desolate, because of all their abominations which they have committed.", "acv": "Then they shall know that I am Jehovah when I have made the land a desolation and an astonishment, because of all their abominations which they have committed.", "anderson": "", "haweis": "", "noyes": "Then shall they know that I am Jehovah, when I have made the land an utter desolation, on account of all the abominations which they practise.", "webster": "Then shall they know that I [am] the LORD, when I have laid the land most desolate because of all their abominations which they have committed.", "vulgate": "et scient quia ego Dominus cum dedero terram desolatam et desertam propter universas abominationes suas quas operati sunt;", "brenton": "And they shall know that I am the Lord; and I will make their land desert, and it shall be made desolate because of all their abominations which they have wrought."}}, {"v": 30, "ref": "33:30", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם בְּנֵ֣י עַמְּ/ךָ֗ הַ/נִּדְבָּרִ֤ים בְּ/ךָ֙ אֵ֣צֶל הַ/קִּיר֔וֹת וּ/בְ/פִתְחֵ֖י הַ/בָּתִּ֑ים וְ/דִבֶּר חַ֣ד אֶת אַחַ֗ד אִ֤ישׁ אֶת אָחִי/ו֙ לֵ/אמֹ֔ר בֹּֽאוּ נָ֣א וְ/שִׁמְע֔וּ מָ֣ה הַ/דָּבָ֔ר הַ/יּוֹצֵ֖א מֵ/אֵ֥ת יְהוָֽה", "en": {"kjv": "Also, thou son of man, the children of thy people still are talking against thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying, Come, I pray you, and hear what is the word that cometh forth from the Lord.", "web": "As for you, son of man, the children of your people talk of you by the walls and in the doors of the houses, and speak one to another, everyone to his brother, saying, Please come and hear what is the word that comes out from Yahweh.", "bsb": "As for you, son of man, your people are talking about you near the city walls and in the doorways of their houses. One speaks to another, each saying to his brother, ‘Come and hear the message that has come from the LORD!’", "asv": "And as for thee, son of man, the children of thy people talk of thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying, Come, I pray you, and hear what is the word that cometh forth from Jehovah.", "ylt": "And thou, son of man, the sons of thy people who are speaking about thee, By the walls, and in openings of the houses, Have spoken one with another, each with his brother, Saying: Come in, I pray you, And hear what is the word that cometh out from Jehovah.", "dra": "And thou son of man: the children of thy people, that talk of thee by the walls, and in the doors of the houses, and speak one to another each man to his neighbour, saying: Come, and let us hear what is the word that cometh forth from the Lord.", "bbe": "And as for you, son of man, the children of your people are talking together about you by the walls and in the doorways of the houses, saying to one another, Come now, give ear to the word which comes from the Lord.", "geneva": "Also thou sonne of man, the children of thy people that talke of thee by the wals and in the dores of houses, and speake one to another, euery one to his brother, saying, Come, I pray you, and heare what is the word that commeth from the Lord.", "wycliffe": "And thou, sone of man, the sones of thi puple that speken of thee bisidis wallis, and in the doris of housis, and seien, oon to an other, a man to his neiybore, and speken, Come ye, and here we, what is the word goynge out fro the Lord;", "rotherham": "Thou therefore Son of man, the sons of thy people who are talking against thee Near the walls and in the entrances of the houses, are speaking one with another, every man with his brother saying. Come in we pray you and heat, what is the word that is coming forth from Yahweh;", "darby": "And as for thee, son of man, the children of thy people keep talking of thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying, Come, I pray you, and hear what is the word that cometh forth from Jehovah.", "twenty": "", "jps": "And as for thee, son of man, the children of thy people that talk of thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying: Come, I pray you, and hear what is the word that cometh forth from HaShem;", "acv": "And as for thee, son of man, the sons of thy people talk of thee by the walls and in the doors of the houses, and speak one to another, each one to his brother, saying, Come, I pray you, and hear what is the word that comes forth from Jehovah.", "anderson": "", "haweis": "", "noyes": "As for thee, O son of man, the sons of thy people speak concerning thee by the walls, and in the doors of houses; and speak one to another, every man to his neighbor, saying, \"Come, I pray you, and hear what is the word that goeth forth from Jehovah.\"", "webster": "Also, thou son of man, the children of thy people still are talking against thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying, Come, I pray you, and hear what is the word that cometh forth from the LORD.", "vulgate": "et tu fili hominis filii populi tui qui loquuntur de te iuxta muros et in ostiis domorum et dicunt unus ad alterum vir ad proximum suum loquentes venite et audiamus qui sit sermo egrediens a Domino;", "brenton": "And as for thee, son of man, the children of thy people are they that speak concerning thee by the walls, and in the porches of the houses, and they talk one to another, saying, Let us come together, and let us hear the words that proceed from the Lord."}}, {"v": 31, "ref": "33:31", "o": "וְ/יָב֣וֹאוּ אֵ֠לֶי/ךָ כִּ/מְבוֹא עָ֞ם וְ/יֵשְׁב֤וּ לְ/פָנֶ֨י/ךָ֙ עַמִּ֔/י וְ/שָֽׁמְעוּ֙ אֶת דְּבָרֶ֔י/ךָ וְ/אוֹתָ֖/ם לֹ֣א יַֽעֲשׂ֑וּ כִּֽי עֲגָבִ֤ים בְּ/פִי/הֶם֙ הֵ֣מָּה עֹשִׂ֔ים אַחֲרֵ֥י בִצְעָ֖/ם לִבָּ֥/ם הֹלֵֽךְ", "en": {"kjv": "And they come unto thee as the people cometh, and they sit before thee as my people, and they hear thy words, but they will not do them: for with their mouth they shew much love, but their heart goeth after their covetousness.", "web": "They come to you as the people come, and they sit before you as my people, and they hear your words, but don’t do them; for with their mouth they show much love, but their heart goes after their gain.", "bsb": "So My people come to you as usual, sit before you, and hear your words; but they do not put them into practice. Although they express love with their mouths, their hearts pursue dishonest gain.", "asv": "And they come unto thee as the people cometh, and they sit before thee as my people, and they hear thy words, but do them not; for with their mouth they show much love, but their heart goeth after their gain.", "ylt": "And they come in unto thee as the coming in of a people, And they sit before thee--My people, And have heard thy words, and they do them not, For doting loves with their mouth they are making, After their dishonest gain their heart is going.", "dra": "And they come to thee, as if people were coming in, and my people sit before thee: and hear thy words, and do them not: for they turn them into a song of their mouth, and their heart goeth after their covetousness.", "bbe": "And they come to you as my people come, and are seated before you as my people, hearing your words but doing them not: for deceit is in their mouth and their heart goes after profit for themselves.", "geneva": "For they come vnto thee, as the people vseth to come: and my people sit before thee, and heare thy wordes, but they will not doe them: for with their mouthes they make iestes, and their heart goeth after their couetousnesse.", "wycliffe": "and thei comen to thee, as if my puple entrith, and my puple sitten bifore thee, and thei heren thi wordis, and doon not tho; for thei turnen tho in to the song of her mouth, and her herte sueth her auerice;", "rotherham": "That they may come unto thee as people do come And may sit before thee as my people, And they will hear thy words, But, the words themselves, will they not do,— though fond with their mouths, they seem to be, After their unjust gain, their heart is going.", "darby": "And they come unto thee as a people cometh, and they sit before thee [as] my people, and they hear thy words, but they do them not; for with their mouth they shew much love, [but] their heart goeth after their dishonest gain.", "twenty": "", "jps": "and come unto thee as the people cometh, and sit before thee as My people, and hear thy words, but do them not--for with their mouth they show much love, but their heart goeth after their covetousness;", "acv": "And they come to thee as the people come, and they sit before thee as my people. And they hear thy words, but do not do them. For with their mouth they show much love, but their heart goes after their gain.", "anderson": "", "haweis": "", "noyes": "And they come to thee, as the people assembleth, and they sit before thee, as my people, and they hear thy words: but will not do them; for with their mouth they do what is lovely, but their heart goeth after gain.", "webster": "And they come to thee as the people come, and they sit before thee [as] my people, and they hear thy words, but they will not do them: for with their mouth they show much love, [but] their heart goeth after their covetousness.", "vulgate": "et veniunt ad te quasi si ingrediatur populus et sedent coram te populus meus et audiunt sermones tuos et non faciunt eos quia in canticum oris sui vertunt illos et avaritiam suam sequitur cor eorum;", "brenton": "They approach thee as a people comes together, and sit before thee, and hear thy words, but they will not do them: for there is falsehood in their mouth, and their heart goes after their pollutions."}}, {"v": 32, "ref": "33:32", "o": "וְ/הִנְּ/ךָ֤ לָ/הֶם֙ כְּ/שִׁ֣יר עֲגָבִ֔ים יְפֵ֥ה ק֖וֹל וּ/מֵטִ֣ב נַגֵּ֑ן וְ/שָֽׁמְעוּ֙ אֶת דְּבָרֶ֔י/ךָ וְ/עֹשִׂ֥ים אֵינָ֖/ם אוֹתָֽ/ם", "en": {"kjv": "And, lo, thou art unto them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument: for they hear thy words, but they do them not.", "web": "Behold, you are to them as a very lovely song of one who has a pleasant voice, and can play well on an instrument; for they hear your words, but they don’t do them.", "bsb": "Indeed, you are to them like a singer of love songs with a beautiful voice, who skillfully plays an instrument. They hear your words but do not put them into practice.", "asv": "And, lo, thou art unto them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument; for they hear thy words, but they do them not.", "ylt": "And lo, thou art to them as a singer of doting loves, A pleasant voice, and playing well on an instrument, And they have heard thy words, and they are not doing them.", "dra": "And thou art to them as a musical song which is sung with a sweet and agreeable voice: and they hear thy words, and do them not.", "bbe": "And truly you are to them like a love song by one who has a very pleasing voice and is an expert player on an instrument: for they give ear to your words but do them not.", "geneva": "And loe, thou art vnto them, as a iesting song of one that hath a pleasant voyce, and can sing well: for they heare thy woordes, but they doe them not.", "wycliffe": "and it is to hem as a song of musik, which is songun bi soft and swete sown; and thei heren thi wordis, and thei doon not tho;", "rotherham": "And lo! thou art to them— As a bewitching song, Of one with a beautiful voice. And skilfully touching the strings, —So will they hear thy words, And yet be going to do none of them.", "darby": "And behold, thou art unto them as a lovely song, a pleasant voice, and one that playeth well on an instrument; and they hear thy words, but they do them not.", "twenty": "", "jps": "and, lo, thou art unto them as a love song of one that hath a pleasant voice, and can play well on an instrument; so they hear thy words, but they do them not--", "acv": "And, lo, thou are to them as a very lovely song of he who has a pleasant voice, and can play well on an instrument. For they hear thy words, but they do not do them.", "anderson": "", "haweis": "", "noyes": "And behold, thou art to them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument; for they hear thy words, but do them not.", "webster": "And lo, thou [art] to them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument: for they hear thy words, but they do not perform them.", "vulgate": "et es eis quasi carmen musicum quod suavi dulcique sono canitur et audient verba tua et non facient ea;", "brenton": "And thou art to them as a sound of a sweet, well-tuned psaltery, and they will hear thy words, but they will not do them."}}, {"v": 33, "ref": "33:33", "o": "וּ/בְ/בֹאָ֑/הּ הִנֵּ֣ה בָאָ֔ה וְ/יָ֣דְע֔וּ כִּ֥י נָבִ֖יא הָיָ֥ה בְ/תוֹכָֽ/ם", "en": {"kjv": "And when this cometh to pass, (lo, it will come,) then shall they know that a prophet hath been among them.", "web": "When this comes to pass, (behold, it comes), then shall they know that a prophet has been among them.", "bsb": "So when it comes to pass—and surely it will come—then they will know that a prophet has been among them.”", "asv": "And when this cometh to pass (behold, it cometh), then shall they know that a prophet hath been among them.", "ylt": "And in its coming in--lo, it hath come, And they have known that a prophet hath been in their midst!'", "dra": "And when that which was foretold shall come to pass, for behold it is coming, then shall they know that a prophet hath been among them.", "bbe": "And when this comes about (see, it is coming), then it will be clear to them that a prophet has been among them.", "geneva": "And when this commeth to passe (for loe, it will come) then shall they know, that a Prophet hath bene among them.", "wycliffe": "and whanne that that is bifore seide cometh, for lo! it cometh, thanne thei schulen wite, that `profetis weren among hem.", "rotherham": "But when it cometh Lo! it is coming, Then shall they know that a prophet hath been in their midst.", "darby": "And when this cometh to pass (behold, it will come), then shall they know that a prophet hath been among them.", "twenty": "", "jps": "when this cometh to pass--behold, it cometh--then shall they know that a prophet hath been among them.'", "acv": "And when this comes to pass, (behold, it comes), then they shall know that a prophet has been among them.", "anderson": "", "haweis": "", "noyes": "But when this cometh to pass, (and behold, it shall come to pass,) then shall they know that a prophet hath been among them.", "webster": "And when this cometh to pass, (lo, it will come,) then shall they know that a prophet hath been among them.", "vulgate": "et cum venerit quod praedictum est ecce enim venit tunc scient quod prophetes fuerit inter eos;", "brenton": "But whenever it shall come to pass, they will say, Behold, it is come: and they shall know that there was a prophet in the midst of them."}}]}, {"c": 34, "verses": [{"v": 1, "ref": "34:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "Then the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, it saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "34:2", "o": "בֶּן אָדָ֕ם הִנָּבֵ֖א עַל רוֹעֵ֣י יִשְׂרָאֵ֑ל הִנָּבֵ֣א וְ/אָמַרְתָּ֩ אֲלֵי/הֶ֨ם לָ/רֹעִ֜ים כֹּ֥ה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה ה֤וֹי רֹעֵֽי יִשְׂרָאֵל֙ אֲשֶׁ֤ר הָיוּ֙ רֹעִ֣ים אוֹתָ֔/ם הֲ/ל֣וֹא הַ/צֹּ֔אן יִרְע֖וּ הָ/רֹעִֽים", "en": {"kjv": "Son of man, prophesy against the shepherds of Israel, prophesy, and say unto them, Thus saith the Lord God unto the shepherds; Woe be to the shepherds of Israel that do feed themselves! should not the shepherds feed the flocks?", "web": "Son of man, prophesy against the shepherds of Israel, prophesy, and tell them, even to the shepherds, Thus says the Lord Yahweh: Woe to the shepherds of Israel who feed themselves! Shouldn’t the shepherds feed the sheep?", "bsb": "“Son of man, prophesy against the shepherds of Israel. Prophesy and tell them that this is what the Lord GOD says: ‘Woe to the shepherds of Israel, who only feed themselves! Should not the shepherds feed their flock?", "asv": "Son of man, prophesy against the shepherds of Israel, prophesy, and say unto them, even to the shepherds, Thus saith the Lord Jehovah: Woe unto the shepherds of Israel that do feed themselves! should not the shepherds feed the sheep?", "ylt": "`Son of man, prophesy concerning shepherds of Israel, prophesy, and thou hast said unto them: To the shepherds, thus said the Lord Jehovah: Woe to the shepherds of Israel, Who have been feeding themselves! The flock do not the shepherds feed?", "dra": "Son of man, prophesy concerning the shepherds of Israel: prophesy, and say to the shepherds: Thus saith the Lord God: Woe to the shepherds of Israel, that fed themselves: should not the flocks be fed by the shepherds?", "bbe": "Son of man, be a prophet against the keepers of the flock of Israel, and say to them, O keepers of the sheep! this is the word of the Lord: A curse is on the keepers of the flock of Israel who take the food for themselves! is it not right for the keepers to give the food to the sheep?", "geneva": "Sonne of man, prophesie against the shepherdes of Israel, prophesie and say vnto them, Thus saieth the Lord God vnto the shepherds, Wo be vnto the shepherds of Israel, that feede them selues: should not the shepherds feede the flockes?", "wycliffe": "and he seide, Sone of man, profesie thou of the schepherdis of Israel, profesie thou; and thou schalt seie to the schepherdis, The Lord God seith these thingis, Wo to the schepherdis of Israel, that fedden hym silf; whether flockis ben not fed of schepherdis?", "rotherham": "Son of man, Prophesy against the shepherds of Israel,- Prophesy, and thou shalt say unto them, even to the shepherds— Thus, saith My Lord Yahweh— Alas! for the shepherds of Israel who have been tending, themselves, Is it not the flock that the shepherds should tend?", "darby": "Son of man, prophesy against the shepherds of Israel, prophesy; and say unto them, unto the shepherds, Thus saith the Lord Jehovah: Woe to the shepherds of Israel that feed themselves! Should not the shepherds feed the flock?", "twenty": "", "jps": "'Son of man, prophesy against the shepherds of Israel, prophesy, and say unto them, even to the shepherds: Thus saith the L-rd GOD: Woe unto the shepherds of Israel that have fed themselves! should not the shepherds feed the sheep?", "acv": "Son of man, prophesy against the shepherds of Israel. Prophesy, and say to them, even to the shepherds, Thus says the Lord Jehovah: Woe to the shepherds of Israel who feed themselves! Should not the shepherds feed the sheep?", "anderson": "", "haweis": "", "noyes": "Son of man, prophesy against the shepherds of Israel; prophesy, and say to them, to the shepherds, Thus saith the Lord Jehovah: Woe to the shepherds of Israel, who feed themselves! Should not the shepherds feed the flocks?", "webster": "Son of man, prophesy against the shepherds of Israel, prophesy, and say to them, Thus saith the Lord GOD to the shepherds; Woe [be] to the shepherds of Israel that do feed themselves! should not the shepherds feed the flocks?", "vulgate": "fili hominis propheta de pastoribus Israhel propheta et dices pastoribus haec dicit Dominus Deus vae pastoribus Israhel qui pascebant semet ipsos nonne greges pascuntur a pastoribus;", "brenton": "Son of man, prophesy against the shepherds of Israel, prophesy, and say to the shepherds, Thus saith the Lord God; O shepherds of Israel, do shepherds feed themselves? do not the shepherds feed the sheep?"}}, {"v": 3, "ref": "34:3", "o": "אֶת הַ/חֵ֤לֶב תֹּאכֵ֨לוּ֙ וְ/אֶת הַ/צֶּ֣מֶר תִּלְבָּ֔שׁוּ הַ/בְּרִיאָ֖ה תִּזְבָּ֑חוּ הַ/צֹּ֖אן לֹ֥א תִרְעֽוּ", "en": {"kjv": "Ye eat the fat, and ye clothe you with the wool, ye kill them that are fed: but ye feed not the flock.", "web": "You eat the fat, and you clothe yourself with the wool, you kill the fatlings; but you don’t feed the sheep.", "bsb": "You eat the fat, wear the wool, and butcher the fattened sheep, but you do not feed the flock.", "asv": "Ye eat the fat, and ye clothe you with the wool, ye kill the fatlings; but ye feed not the sheep.", "ylt": "The fat ye do eat, and the wool ye put on, The fed one ye slaughter, the flock ye feed not.", "dra": "You ate the milk, and you clothed yourselves with the wool, and you killed that which was fat: but my flock you did not feed.", "bbe": "You take the milk and are clothed with the wool, you put the fat beasts to death, but you give the sheep no food.", "geneva": "Yee eate the fat, and yee clothe you with the wooll: yee kill them that are fed, but ye feede not the sheepe.", "wycliffe": "Ye eeten mylk, and weren hilid with wollis, and ye killiden that that was fat; but ye fedden not my floc.", "rotherham": "The milk, ye do eat And with the wool, ye do clothe your- selves, The well-fed, ye do sacrifice, The flock, ye do not tend", "darby": "Ye eat the fat, and ye clothe you with the wool; ye kill them that are fattened: [but] ye feed not the flock.", "twenty": "", "jps": "Ye did eat the fat, and ye clothed you with the wool, ye killed the fatlings; but ye fed not the sheep.", "acv": "Ye eat the fat, and ye clothe yourselves with the wool. Ye kill the fatlings, but ye do not feed the sheep.", "anderson": "", "haweis": "", "noyes": "Ye eat the fat, and ye clothe you with the wool, ye kill that which is fatted; but ye feed not the flock.", "webster": "Ye eat the fat, and ye clothe yourselves with the wool, ye kill them that are fed: [but] ye feed not the flock.", "vulgate": "lac comedebatis et lanis operiebamini et quod crassum erat occidebatis gregem autem meum non pascebatis;", "brenton": "Behold, ye feed on the milk, and clothe yourselves with the wool, and slay the fat: but ye feed not my sheep."}}, {"v": 4, "ref": "34:4", "o": "אֶֽת הַ/נַּחְלוֹת֩ לֹ֨א חִזַּקְתֶּ֜ם וְ/אֶת הַ/חוֹלָ֣ה לֹֽא רִפֵּאתֶ֗ם וְ/לַ/נִּשְׁבֶּ֨רֶת֙ לֹ֣א חֲבַשְׁתֶּ֔ם וְ/אֶת הַ/נִּדַּ֨חַת֙ לֹ֣א הֲשֵׁבֹתֶ֔ם וְ/אֶת הָ/אֹבֶ֖דֶת לֹ֣א בִקַּשְׁתֶּ֑ם וּ/בְ/חָזְקָ֛ה רְדִיתֶ֥ם אֹתָ֖/ם וּ/בְ/פָֽרֶךְ", "en": {"kjv": "The diseased have ye not strengthened, neither have ye healed that which was sick, neither have ye bound up that which was broken, neither have ye brought again that which was driven away, neither have ye sought that which was lost; but with force and with cruelty have ye ruled them.", "web": "You haven’t strengthened the diseased, neither have you healed that which was sick, neither have you bound up that which was broken, neither have you brought back that which was driven away, neither have you sought that which was lost; but with force and with rigor you have ruled over them.", "bsb": "You have not strengthened the weak, healed the sick, bound up the injured, brought back the strays, or searched for the lost. Instead, you have ruled them with violence and cruelty.", "asv": "The diseased have ye not strengthened, neither have ye healed that which was sick, neither have ye bound up that which was broken, neither have ye brought back that which was driven away, neither have ye sought that which was lost; but with force and with rigor have ye ruled over them.", "ylt": "The weak ye have not strengthened, And the sick one ye have not healed, And the broken ye have not bound up, And the driven away have not brought back, And the lost ye have not sought, And with might ye have ruled them and with rigour.", "dra": "The weak you have not strengthened, and that which was sick you have not healed, that which was broken you have not bound up, and that which was driven away you have not brought again, neither have you sought that which was lost: but you ruled over them with rigour, and with a high hand.", "bbe": "You have not made the diseased ones strong or made well that which was ill; you have not put bands on the broken or got back that which had been sent away or made search for the wandering ones; and the strong you have been ruling cruelly.", "geneva": "The weake haue ye not strengthened: the sicke haue ye not healed, neither haue ye bounde vp the broken, nor brought againe that which was driuen away, neither haue yee sought that which was lost, but with crueltie, and with rigour haue yee ruled them.", "wycliffe": "Ye maden not sad that that was vnstidfast, and ye maden not hool that that was sijk; ye bounden not that that was brokun, and ye brouyten not ayen that that was cast awei, and ye souyten not that that perischide; but ye comaundiden to hem with sturnenesse, and with power.", "rotherham": "The weak, have ye not strengthened And, the sick, have ye not healed. And the torn, have ye not bound up, And that which was driven out, have ye not brought back, And that which was straying, have ye not sought out; But with force, have ye ruled them and with rigour.", "darby": "The weak have ye not strengthened, nor have ye healed the sick, and ye have not bound up [what was] broken, neither have ye brought again that which was driven away, neither have ye sought for that which was lost; but with harshness and with rigour have ye ruled over them.", "twenty": "", "jps": "The weak have ye not strengthened, neither have ye healed that which was sick, neither have ye bound up that which was broken, neither have ye brought back that which was driven away, neither have ye sought that which was lost; but with force have ye ruled over them and with rigour.", "acv": "Ye have not strengthened the diseased, nor have ye healed that which was sick, nor have ye bound up that which was broken, nor have ye brought back that which was driven away, nor have ye sought that which was lost, but ye have ruled over them with force and with rigor.", "anderson": "", "haweis": "", "noyes": "The weak do ye not strengthen, and the sick do ye not heal, and the wounded do ye not bind up; ye bring not back that which hath been driven away, neither seek ye that which hath been lost; but with force and with cruelty do ye rule them.", "webster": "The diseased ye have not strengthened, neither have ye healed that which was sick, neither have ye bound up [that which was] broken, neither have ye brought again that which was driven away, neither have ye sought that which was lost; but with force and with cruelty have ye ruled them.", "vulgate": "quod infirmum fuit non consolidastis et quod aegrotum non sanastis quod fractum est non alligastis et quod abiectum est non reduxistis quod perierat non quaesistis sed cum austeritate imperabatis eis et cum potentia;", "brenton": "The weak one ye have not strengthened, and the sick ye have not cherished, and the bruised ye have not bound up, and the stray one ye have not turned back, and the lost ye have not sought; and the strong ye have wearied with labour."}}, {"v": 5, "ref": "34:5", "o": "וַ/תְּפוּצֶ֖ינָה מִ/בְּלִ֣י רֹעֶ֑ה וַ/תִּהְיֶ֧ינָה לְ/אָכְלָ֛ה לְ/כָל חַיַּ֥ת הַ/שָּׂדֶ֖ה וַ/תְּפוּצֶֽינָה", "en": {"kjv": "And they were scattered, because there is no shepherd: and they became meat to all the beasts of the field, when they were scattered.", "web": "They were scattered, because there was no shepherd; and they became food to all the animals of the field, and were scattered.", "bsb": "They were scattered for lack of a shepherd, and when they were scattered they became food for all the wild beasts.", "asv": "And they were scattered, because there was no shepherd; and they became food to all the beasts of the field, and were scattered.", "ylt": "And they are scattered from want of a shepherd, And are for food to every beast of the field, Yea, they are scattered.", "dra": "And my sheep were scattered, because there was no shepherd and they became the prey of all the beasts of the field, and were scattered.", "bbe": "And they were wandering in every direction because there was no keeper: and they became food for all the beasts of the field.", "geneva": "And they were scattered without a shepherde: and when they were dispersed, they were deuoured of all the beastes of the fielde.", "wycliffe": "And my scheep weren scaterid, for no sheepherde was; and thei weren maad in to deuouryng of alle beestis of the feeld, and thei weren scaterid.", "rotherham": "And they were scattered, because there was no shepherd; And they became food for every wild beast of the field. So were they scattered.", "darby": "And they were scattered because there was no shepherd; and they became meat to all the beasts of the field, and were scattered.", "twenty": "", "jps": "So were they scattered, because there was no shepherd; and they became food to all the beasts of the field, and were scattered.", "acv": "And they were scattered because there was no shepherd. And they became food to all the beasts of the field, and were scattered.", "anderson": "", "haweis": "", "noyes": "Therefore are they scattered abroad, because there is no shepherd, and they are food to all the beasts of the field, or are scattered abroad.", "webster": "And they were scattered, because [there is] no shepherd: and they became food to all the beasts of the field, when they were scattered.", "vulgate": "et dispersae sunt oves meae eo quod non esset pastor et factae sunt in devorationem omnium bestiarum agri et dispersae sunt;", "brenton": "And my sheep were scattered, because there were no shepherds: and they became meat to all the wild beasts of the field."}}, {"v": 6, "ref": "34:6", "o": "יִשְׁגּ֤וּ צֹאנִ/י֙ בְּ/כָל הֶ֣/הָרִ֔ים וְ/עַ֖ל כָּל גִּבְעָ֣ה רָמָ֑ה וְ/עַ֨ל כָּל פְּנֵ֤י הָ/אָ֨רֶץ֙ נָפֹ֣צוּ צֹאנִ֔/י וְ/אֵ֥ין דּוֹרֵ֖שׁ וְ/אֵ֥ין מְבַקֵּֽשׁ", "en": {"kjv": "My sheep wandered through all the mountains, and upon every high hill: yea, my flock was scattered upon all the face of the earth, and none did search or seek after them.", "web": "My sheep wandered through all the mountains, and on every high hill: yes, my sheep were scattered on all the surface of the earth; and there was no one who searched or sought.", "bsb": "My flock went astray on all the mountains and every high hill. They were scattered over the face of all the earth, with no one to search for them or seek them out.’", "asv": "My sheep wandered through all the mountains, and upon every high hill: yea, my sheep were scattered upon all the face of the earth; and there was none that did search or seek after them.", "ylt": "Go astray do My flock on all the mountains, And on every high hill, And on all the face of the land have My flock been scattered, And there is none inquiring, and none seeking.", "dra": "My sheep have wandered in every mountain, and in every high hill: and my flocks were scattered upon the face of the earth, and there was none that sought them, there was none, I say, that sought them.", "bbe": "And my sheep went out of the way, wandering through all the mountains and on every high hill: my sheep went here and there over all the face of the earth; and no one was troubled about them or went in search of them.", "geneva": "My sheepe wandred through all the mountaines, and vpon euery hie hill: yea, my flocke was scattered through al the earth, and none did seeke or search after them.", "wycliffe": "My flockis erriden in alle mounteyns, and in ech hiy hil, and my flockis weren scaterid on al the face of erthe, and noon was that souyte.", "rotherham": "My sheep did wander through all the mountains, And over every high hill,- And over all the face of the land, were my sheep scattered, And there was none to inquire And none to seek out.", "darby": "My sheep wandered through all the mountains, and upon every high hill, and my sheep have been scattered upon all the face of the earth, and there was none that searched, or that sought for them.", "twenty": "", "jps": "My sheep wandered through all the mountains, and upon every high hill, yea, upon all the face of the earth were My sheep scattered, and there was none that did search or seek.", "acv": "My sheep wandered through all the mountains, and upon every high hill. Yea, my sheep were scattered upon all the face of the earth, and there was none who searched or sought.", "anderson": "", "haweis": "", "noyes": "My sheep wander through all the mountains, and upon every high hill; yea, over the whole face of the land is my flock scattered, and none careth for them, or seeketh them.", "webster": "My sheep wandered through all the mountains, and upon every high hill: yes, my flock was scattered upon all the face of the earth, and none did search or seek [for them].", "vulgate": "erraverunt greges mei in cunctis montibus et in universo colle excelso et super omnem faciem terrae dispersi sunt greges mei et non erat qui requireret non erat inquam qui requireret;", "brenton": "And my sheep were scattered on every mountain, and on every high hill: yea, they were scattered on the face of the earth, and there was none to seek them out, nor to bring them back."}}, {"v": 7, "ref": "34:7", "o": "לָ/כֵ֣ן רֹעִ֔ים שִׁמְע֖וּ אֶת דְּבַ֥ר יְהוָֽה", "en": {"kjv": "Therefore, ye shepherds, hear the word of the Lord;", "web": "Therefore, you shepherds, hear Yahweh’s word:", "bsb": "Therefore, you shepherds, hear the word of the LORD:", "asv": "Therefore, ye shepherds, hear the word of Jehovah:", "ylt": "Therefore, shepherds, hear a word of Jehovah:", "dra": "Therefore, ye shepherds, hear the word of the Lord:", "bbe": "For this cause, O keepers of the flock, give ear to the word of the Lord:", "geneva": "Therefore ye shepherds, heare the woorde of the Lord.", "wycliffe": "Therfor, scheepherdis, here ye the word of the Lord;", "rotherham": "Wherefore ye shepherds, hear ye the word of Yahweh:", "darby": "Therefore, ye shepherds, hear the word of Jehovah:", "twenty": "", "jps": "Therefore, ye shepherds, hear the word of HaShem:", "acv": "Therefore, ye shepherds, hear the word of Jehovah:", "anderson": "", "haweis": "", "noyes": "Therefore, ye shepherds, hear the word of Jehovah:", "webster": "Therefore, ye shepherds, hear the word of the LORD;", "vulgate": "propterea pastores audite verbum Domini;", "brenton": "Therefore, ye shepherds, hear the word of the Lord."}}, {"v": 8, "ref": "34:8", "o": "חַי אָ֜נִי נְאֻ֣ם אֲדֹנָ֣/י יְהוִ֗ה אִם לֹ֣א יַ֣עַן הֱיֽוֹת צֹאנִ֣/י לָ/בַ֡ז וַ/תִּֽהְיֶינָה֩ צֹאנִ֨/י לְ/אָכְלָ֜ה לְ/כָל חַיַּ֤ת הַ/שָּׂדֶה֙ מֵ/אֵ֣ין רֹעֶ֔ה וְ/לֹֽא דָרְשׁ֥וּ רֹעַ֖/י אֶת צֹאנִ֑/י וַ/יִּרְע֤וּ הָֽ/רֹעִים֙ אוֹתָ֔/ם וְ/אֶת צֹאנִ֖/י לֹ֥א רָעֽוּ", "en": {"kjv": "As I live, saith the Lord God, surely because my flock became a prey, and my flock became meat to every beast of the field, because there was no shepherd, neither did my shepherds search for my flock, but the shepherds fed themselves, and fed not my flock;", "web": "As I live, says the Lord Yahweh, surely because my sheep became a prey, and my sheep became food to all the animals of the field, because there was no shepherd, neither did my shepherds search for my sheep, but the shepherds fed themselves, and didn’t feed my sheep;", "bsb": "‘As surely as I live, declares the Lord GOD, because My flock lacks a shepherd and has become prey and food for every wild beast, and because My shepherds did not search for My flock but fed themselves instead,", "asv": "As I live, saith the Lord Jehovah, surely forasmuch as my sheep became a prey, and my sheep became food to all the beasts of the field, because there was no shepherd, neither did my shepherds search for my sheep, but the shepherds fed themselves, and fed not my sheep;", "ylt": "I live--an affirmation of the Lord Jehovah, If not, because of My flock being for a prey, Yea, My flock is for food to every beast of the field, Because there is no shepherd, And My shepherds have not sought My flock, And the shepherds do feed themselves, And My flock they have not fed.", "dra": "As I live, saith the Lord God, forasmuch as my flocks have been made a spoil, and my sheep are become a prey to all the beasts of the field, because there was no shepherd: for my shepherds did not seek after my flock, but the shepherds fed themselves, and fed not my flocks:", "bbe": "By my life, says the Lord, truly, because my sheep have been taken away, and my sheep became food for all the beasts of the field, because there was no keeper, and my keepers did not go in search of the sheep, but the keepers took food for themselves and gave my sheep no food;", "geneva": "As I liue, sayeth the Lord God, surely because my flocke was spoyled, and my sheepe were deuoured of all the beasts of the fielde, hauing no shepherde, neither did my shepherdes seeke my sheepe, but the shepherdes fedde them selues, and fedde not my sheepe,", "wycliffe": "Y lyue, seith the Lord God, for whi for that that my flockis ben maad in to raueyn, and my scheep in to deuouryng of alle beestis of the feeld, for that that no scheepherde was, for the scheepherdis souyten not my floc, but the scheepherdis fedden hem silf, and fedden not my flockis; therfor,", "rotherham": "As I live,— Declareth My Lord Yahweh, Surely because my flock became a prey. And my flock became food for every wild beast of the field, through having no shepherd, Neither did my shepherds inquire after the flock, —But the shepherds tended themselves. And my flock, they tended not", "darby": "[As] I live, saith the Lord Jehovah, verily because my sheep have been a prey, and my sheep have been meat to every beast of the field, because there was no shepherd, and my shepherds searched not for my flock, but the shepherds fed themselves, and fed not my flock,", "twenty": "", "jps": "As I live, saith the L-rd GOD, surely forasmuch as My sheep became a prey, and My sheep became food to all the beasts of the field, because there was no shepherd, neither did My shepherds search for My sheep, but the shepherds fed themselves, and fed not My sheep;", "acv": "As I live, says the lord Jehovah, surely inasmuch as my sheep became a prey, and my sheep became food to all the beasts of the field, because there was no shepherd, nor did my shepherds search for my sheep, but the shepherds fed themselves, and did not feed my sheep,", "anderson": "", "haweis": "", "noyes": "As I live, saith the Lord Jehovah, surely, because my flock is become a prey, and my flock is become meat to all the beasts of the field because there is no shepherd, and because my shepherds search not for my flock, and feed themselves, and feed not my flock,—", "webster": "[As] I live, saith the Lord GOD, surely because my flock became a prey, and my flock became food to every beast of the field, because [there was] no shepherd, neither did my shepherds search for my flock, but the shepherds fed themselves, and fed not my flock;", "vulgate": "vivo ego dicit Dominus Deus quia pro eo quod facti sunt greges mei in rapinam et oves meae in devorationem omnium bestiarum agri eo quod non esset pastor neque enim quaesierunt pastores gregem meum sed pascebant pastores semet ipsos et greges meos non pascebant;", "brenton": "As I live, saith the Lord God, surely because my sheep became a prey, and my sheep became meat to all the wild beasts of the field, because there were no shepherds, and the shepherds sought not out my sheep, and the shepherds fed themselves, but fed not my sheep."}}, {"v": 9, "ref": "34:9", "o": "לָ/כֵן֙ הָֽ/רֹעִ֔ים שִׁמְע֖וּ דְּבַר יְהוָֽה", "en": {"kjv": "Therefore, O ye shepherds, hear the word of the Lord;", "web": "therefore, you shepherds, hear Yahweh’s word:", "bsb": "therefore, you shepherds, hear the word of the LORD!’", "asv": "therefore, ye shepherds, hear the word of Jehovah:", "ylt": "Therefore, O shepherds, hear a word of Jehovah:", "dra": "Therefore, ye shepherds, hear the word of the Lord:", "bbe": "For this reason, O you keepers of the flock, give ear to the word of the Lord;", "geneva": "Therefore, heare ye the word of the Lord, O ye shepherds.", "wycliffe": "scheepherdis, here ye the word of the Lord,", "rotherham": "Therefore ye shepherds, hear ye the word of Yahweh:", "darby": "— therefore, ye shepherds, hear the word of Jehovah.", "twenty": "", "jps": "therefore, ye shepherds, hear the word of HaShem:", "acv": "therefore, ye shepherds, hear the word of Jehovah.", "anderson": "", "haweis": "", "noyes": "therefore, ye shepherds, hear the word of Jehovah.", "webster": "Therefore, O ye shepherds, hear the word of the LORD;", "vulgate": "propterea pastores audite verbum Domini;", "brenton": "For this cause, O shepherds,"}}, {"v": 10, "ref": "34:10", "o": "כֹּה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה הִנְ/נִ֨י אֶֽל הָ/רֹעִ֜ים וְֽ/דָרַשְׁתִּ֧י אֶת צֹאנִ֣/י מִ/יָּדָ֗/ם וְ/הִשְׁבַּתִּי/ם֙ מֵ/רְע֣וֹת צֹ֔אן וְ/לֹא יִרְע֥וּ ע֛וֹד הָ/רֹעִ֖ים אוֹתָ֑/ם וְ/הִצַּלְתִּ֤י צֹאנִ/י֙ מִ/פִּי/הֶ֔ם וְ/לֹֽא תִהְיֶ֥יןָ לָ/הֶ֖ם לְ/אָכְלָֽה", "en": {"kjv": "Thus saith the Lord God; Behold, I am against the shepherds; and I will require my flock at their hand, and cause them to cease from feeding the flock; neither shall the shepherds feed themselves any more; for I will deliver my flock from their mouth, that they may not be meat for them.", "web": "Thus says the Lord Yahweh: Behold, I am against the shepherds; and I will require my sheep at their hand, and cause them to cease from feeding the sheep; neither shall the shepherds feed themselves any more; and I will deliver my sheep from their mouth, that they may not be food for them.", "bsb": "This is what the Lord GOD says: ‘Behold, I am against the shepherds, and I will demand from them My flock and remove them from tending the flock, so that they can no longer feed themselves. For I will deliver My flock from their mouths, and it will no longer be food for them.’", "asv": "Thus saith the Lord Jehovah, Behold, I am against the shepherds; and I will require my sheep at their hand, and cause them to cease from feeding the sheep; neither shall the shepherds feed themselves any more; and I will deliver my sheep from their mouth, that they may not be food for them.", "ylt": "Thus said the Lord Jehovah: Lo, I am against the shepherds, And have required My flock from their hand, And caused them to cease from feeding the flock, And no more do the shepherds feed themselves, And I have delivered My flock from their mouth, And they are not to them for food.", "dra": "Thus saith the Lord God: Behold I myself come upon the shepherds, I will require my flock at their hand, and I will cause them to cease from feeding the flock any more, neither shall the shepherds feed themselves any more: and I will deliver my flock from their mouth, and it shall no more be meat for them.", "bbe": "This is what the Lord has said: See I am against the keepers of the flock, and I will make search and see what they have done with my sheep, and will let them be keepers of my sheep no longer; and the keepers will no longer get food for themselves; I will take my sheep out of their mouths so that they may not be food for them.", "geneva": "Thus saieth the Lord God, Behold, I come against the shepherds, and will require my sheepe at their hands, and cause them to cease from feeding the sheepe: neither shall the shepherds feede them selues any more: for I wil deliuer my sheepe from their mouthes, and they shall no more deuoure them.", "wycliffe": "The Lord God seith these thingis, Lo! Y my silf am ouer scheepherdis; Y schal seke my floc of the hond of hem, and Y schal make hem to ceesse, that thei fede no more my flok, and that the scheepherdis feede no more hem silf. And Y schal delyuere my floc fro the mouth of hem, and it schal no more be in to mete to hem.", "rotherham": "Thus, saith My Lord. Yahweh, Behold me! against the shepherds So then I will require my flock at their hand And will cause them to cease tending the flock, Neither shall the shepherds any longer tend themselves, But I will deliver my flock out of their mouth, that they may not be their food.", "darby": "Thus saith the Lord Jehovah: Behold, I am against the shepherds; and I will require my sheep at their hand, and cause them to cease from feeding the flock: that the shepherds may feed themselves no more; and I will deliver my sheep from their mouth, that they may not be food for them.", "twenty": "", "jps": "Thus saith the L-rd GOD: Behold, I am against the shepherds; and I will require My sheep at their hand, and cause them to cease from feeding the sheep; neither shall the shepherds feed themselves any more; and I will deliver My sheep from their mouth, that they may not be food for them.", "acv": "Thus says the lord Jehovah: Behold, I am against the shepherds, and I will require my sheep at their hand, and cause them to cease from feeding the sheep. Neither shall the shepherds feed themselves any more, and I will deliver my sheep from their mouth, that they may not be food for them.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Behold, I am against the shepherds, and I will require my flock at their hand, and cause them to cease from feeding the flock; neither shall the shepherds feed themselves any more; for I will deliver my flock from their mouth, and they shall not be meat for them.", "webster": "Thus saith the Lord GOD; Behold, I [am] against the shepherds; and I will require my flock at their hand, and cause them to cease from feeding the flock; neither shall the shepherds feed themselves any more; for I will deliver my flock from their mouth, that they may not be food for them.", "vulgate": "haec dicit Dominus Deus ecce ego ipse super pastores requiram gregem meum de manu eorum et cessare eos faciam ut ultra non pascant gregem nec pascant amplius pastores semet ipsos et liberabo gregem meum de ore eorum et non erunt ultra eis in escam;", "brenton": "thus saith the Lord God, Behold, I am against the shepherds; and I will require my sheep at their hands, and will turn them back that they shall not feed my sheep, and the shepherds shall no longer feed them; and I will deliver my sheep out of their mouth, and they shall no longer be meat for them."}}, {"v": 11, "ref": "34:11", "o": "כִּ֛י כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הִנְ/נִי אָ֕נִי וְ/דָרַשְׁתִּ֥י אֶת צֹאנִ֖/י וּ/בִקַּרְתִּֽי/ם", "en": {"kjv": "For thus saith the Lord God; Behold, I, even I, will both search my sheep, and seek them out.", "web": "For thus says the Lord Yahweh: Behold, I myself, even I, will search for my sheep, and will seek them out.", "bsb": "For this is what the Lord GOD says: ‘Behold, I Myself will search for My flock and seek them out.", "asv": "For thus saith the Lord Jehovah: Behold, I myself, even I, will search for my sheep, and will seek them out.", "ylt": "For thus said the Lord Jehovah: Lo, I--even I, have required My flock, And I have sought it out.", "dra": "For thus saith the Lord God: Behold I myself will seek my sheep, and will visit them.", "bbe": "For this is what the Lord has said: Truly, I, even I, will go searching and looking for my sheep.", "geneva": "For thus sayeth the Lord God, Beholde, I will search my sheepe, and seeke them out.", "wycliffe": "For the Lord God seith these thingis, Lo! Y my silf schal seke my scheep, and Y schal visite hem.", "rotherham": "For Thus saith My Lord. Yahweh,- Here am I myself Therefore will I inquire after my flock and seek them out:", "darby": "For thus saith the Lord Jehovah: Behold I, [even] I, will both search for my sheep, and tend them.", "twenty": "", "jps": "For thus saith the L-rd GOD: Behold, here am I, and I will search for My sheep, and seek them out.", "acv": "For thus says the lord Jehovah: Behold, I myself, even I, will search for my sheep, and will seek them out.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: Behold I, even I, will seek my flock, and look after them;", "webster": "For thus saith the Lord GOD; Behold, I [even] I, will both search for my sheep, and seek them out.", "vulgate": "quia haec dicit Dominus Deus ecce ego ipse requiram oves meas et visitabo eas;", "brenton": "For thus saith the Lord God, Behold, I will seek out my sheep, and will visit them."}}, {"v": 12, "ref": "34:12", "o": "כְּ/בַקָּרַת֩ רֹעֶ֨ה עֶדְר֜/וֹ בְּ/יוֹם הֱיוֹת֤/וֹ בְ/תוֹךְ צֹאנ/וֹ֙ נִפְרָשׁ֔וֹת כֵּ֖ן אֲבַקֵּ֣ר אֶת צֹאנִ֑/י וְ/הִצַּלְתִּ֣י אֶתְ/הֶ֗ם מִ/כָּל הַ/מְּקוֹמֹת֙ אֲשֶׁ֣ר נָפֹ֣צוּ שָׁ֔ם בְּ/י֥וֹם עָנָ֖ן וַ/עֲרָפֶֽל", "en": {"kjv": "As a shepherd seeketh out his flock in the day that he is among his sheep that are scattered; so will I seek out my sheep, and will deliver them out of all places where they have been scattered in the cloudy and dark day.", "web": "As a shepherd seeks out his flock in the day that he is among his sheep that are scattered abroad, so will I seek out my sheep; and I will deliver them out of all places where they have been scattered in the cloudy and dark day.", "bsb": "As a shepherd looks for his scattered sheep when he is among the flock, so I will look for My flock. I will rescue them from all the places to which they were scattered on a day of clouds and darkness.", "asv": "As a shepherd seeketh out his flock in the day that he is among his sheep that are scattered abroad, so will I seek out my sheep; and I will deliver them out of all places whither they have been scattered in the cloudy and dark day.", "ylt": "As a shepherd's searching of his drove, In the day of his being in the midst of his scattered flock, so I do seek My flock, And have delivered them out of all places, Whither they have been scattered, In a day of cloud and thick darkness.", "dra": "As the shepherd visiteth his flock in the day when he shall be in the midst of his sheep that were scattered, so will I visit my sheep, and will deliver them out of all the places where they have been scattered in the cloudy and dark day.", "bbe": "As the keeper goes looking for his flock when he is among his wandering sheep, so I will go looking for my sheep, and will get them safely out of all the places where they have been sent wandering in the day of clouds and black night.", "geneva": "As a shepherd searcheth out his flocke, when he hath bene among his sheepe that are scattered, so wil I seeke out my sheepe and wil deliuer them out of all places, where they haue beene scattered in the cloudie and darke day,", "wycliffe": "As a scheepherde visitith his floc, in the dai whanne he is in the myddis of hise scheep `that ben scaterid, so Y schal visite my scheep; and Y schal delyuere hem fro alle places in whiche thei weren scaterid, in the dai of cloude, and of derknesse.", "rotherham": "As a shepherd seeketh out his flock in the day he is in the midst of his sheep that are scattered, So! will I seek out my sheep, and will deliver them out of all the places where they were scattered in the day of cloud and thick darkness;", "darby": "As a shepherd tendeth his flock in the day that he is among his scattered sheep, so will I tend my sheep, and will deliver them out of all places whither they have been scattered in the cloudy and dark day.", "twenty": "", "jps": "As a shepherd seeketh out his flock in the day that he is among his sheep that are separated, so will I seek out My sheep; and I will deliver them out of all places whither they have been scattered in the day of clouds and thick darkness.", "acv": "As a shepherd seeks out his flock, in the day that he is among his sheep that are scattered abroad, so I will seek out my sheep, and I will deliver them out of all places where they have been scattered in the cloudy and dark day.", "anderson": "", "haweis": "", "noyes": "as a shepherd looketh after his flock in the day when he is among his sheep that are scattered, so will I look after my sheep, and will deliver them out of all the places where they have been scattered in the day of clouds and darkness.", "webster": "As a shepherd seeketh out his flock in the day that he is among his sheep [that are] scattered; so will I seek out my sheep, and will deliver them out of all places where they have been scattered in the cloudy and dark day.", "vulgate": "sicut visitat pastor gregem suum in die quando fuerit in medio ovium suarum dissipatarum sic visitabo oves meas et liberabo eas de omnibus locis quo dispersae fuerant in die nubis et caliginis;", "brenton": "As the shepherd seeks his flock, in the day when there is darkness and cloud, in the midst of the sheep that are separated: so will I seek out my sheep, and will bring them back from every place where they were scattered in the day of cloud and darkness."}}, {"v": 13, "ref": "34:13", "o": "וְ/הוֹצֵאתִ֣י/ם מִן הָ/עַמִּ֗ים וְ/קִבַּצְתִּי/ם֙ מִן הָ֣/אֲרָצ֔וֹת וַ/הֲבִיאֹתִ֖י/ם אֶל אַדְמָתָ֑/ם וּ/רְעִיתִי/ם֙ אֶל הָרֵ֣י יִשְׂרָאֵ֔ל בָּ/אֲפִיקִ֕ים וּ/בְ/כֹ֖ל מוֹשְׁבֵ֥י הָ/אָֽרֶץ", "en": {"kjv": "And I will bring them out from the people, and gather them from the countries, and will bring them to their own land, and feed them upon the mountains of Israel by the rivers, and in all the inhabited places of the country.", "web": "I will bring them out from the peoples, and gather them from the countries, and will bring them into their own land; and I will feed them on the mountains of Israel, by the watercourses, and in all the inhabited places of the country.", "bsb": "I will bring them out from the peoples, gather them from the countries, and bring them into their own land. I will feed them on the mountains of Israel, in the ravines, and in all the settlements of the land.", "asv": "And I will bring them out from the peoples, and gather them from the countries, and will bring them into their own land; and I will feed them upon the mountains of Israel, by the watercourses, and in all the inhabited places of the country.", "ylt": "And brought them out from the peoples, And have gathered them from the lands, And brought them unto their own ground, And have fed them on mountains of Israel, By streams, and by all dwellings of the land.", "dra": "And I will bring them out from the peoples, and will gather them out of the countries, and will bring them to their own land: and I will feed them in the mountains of Israel, by the rivers, and in all the habitations of the land.", "bbe": "And I will take them out from among the peoples, and get them together from the countries, and will take them into their land; and I will give them food on the mountains of Israel by the water-streams and wherever men are living in the country.", "geneva": "And I will bring them out from the people, and gather them from the countreis, and will bring them to their owne lande, and feede them vpon the mountaines of Israel, by the riuers, and in all the inhabited places of the countrey.", "wycliffe": "And Y schal leede hem out of puplis, and Y schal gadere hem fro londis, and Y schal brynge hem in to her lond, and Y schal feede hem in the hillis of Israel, in ryueris, and in alle seetis of erthe.", "rotherham": "And I will bring them out from among the peoples And will gather them out of the lands, And will bring them upon their own soil, And will tend them Upon the mountains of Israel, In the ravines. And in all the habitable places of the land:", "darby": "And I will bring them out from the peoples, and gather them from the countries, and will bring them to their own land; and I will feed them upon the mountains of Israel by the water-courses, and in all the habitable places of the country.", "twenty": "", "jps": "And I will bring them out from the peoples, and gather them from the countries, and will bring them into their own land; and I will feed them upon the mountains of Israel, by the streams, and in all the habitable places of the country.", "acv": "And I will bring them out from the peoples, and gather them from the countries, and will bring them into their own land. And I will feed them upon the mountains of Israel, by the watercourses, and in all the inhabited places of the country.", "anderson": "", "haweis": "", "noyes": "And I will bring them out from the nations, and gather them from the countries; and I will bring them to their own land, and feed them upon the mountains of Israel, in the valleys, and in all the dwelling-places of the land.", "webster": "And I will bring them out from the people, and gather them from the countries, and will bring them to their own land, and feed them upon the mountains of Israel by the rivers, and in all the inhabited places of the country.", "vulgate": "et educam eas de populis et congregabo eas de terris et inducam eas in terram suam et pascam eas in montibus Israhel in rivis et in cunctis sedibus terrae;", "brenton": "And I will bring them out from the Gentiles, and will gather them from the countries, and will bring them into their own land, and will feed them upon the mountains of Israel, and in the valleys, and in every inhabited place of the land."}}, {"v": 14, "ref": "34:14", "o": "בְּ/מִרְעֶה טּוֹב֙ אֶרְעֶ֣ה אֹתָ֔/ם וּ/בְ/הָרֵ֥י מְרֽוֹם יִשְׂרָאֵ֖ל יִהְיֶ֣ה נְוֵ/הֶ֑ם שָׁ֤ם תִּרְבַּ֨צְנָה֙ בְּ/נָ֣וֶה טּ֔וֹב וּ/מִרְעֶ֥ה שָׁמֵ֛ן תִּרְעֶ֖ינָה אֶל הָרֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be: there shall they lie in a good fold, and in a fat pasture shall they feed upon the mountains of Israel.", "web": "I will feed them with good pasture; and on the mountains of the height of Israel shall their fold be: there shall they lie down in a good fold; and on fat pasture shall they feed on the mountains of Israel.", "bsb": "I will feed them in good pasture, and the lofty mountains of Israel will be their grazing land. There they will lie down in a good grazing land; they will feed in rich pasture on the mountains of Israel.", "asv": "I will feed them with good pasture; and upon the mountains of the height of Israel shall their fold be: there shall they lie down in a good fold; and on fat pasture shall they feed upon the mountains of Israel.", "ylt": "With good pasture I do feed them, And on mountains of the high place of Israel is their habitation, There do they lie down in a good habitation, And fat pastures they enjoy on mountains of Israel.", "dra": "I will feed them in the most fruitful pastures, and their pastures shall be in the high mountains of Israel: there shall they rest on the green grass, and be fed in fat pastures upon the mountains of Israel.", "bbe": "I will give them good grass-land for their food, and their safe place will be the mountains of the high place of Israel: there they will take their rest in a good place, and on fat grass-land they will take their food on the mountains of Israel.", "geneva": "I will feede them in a good pasture, and vpon the hie mountaines of Israel shall their folde be: there shall they lie in a good folde and in fat pasture shall they feede vpon the mountaines of Israel.", "wycliffe": "Y schal feede hem in moost plenteouse pasturis, and the lesewis of hem schulen be in the hiy hillis of Israel; there thei schulen reste in greene eerbis, and in fatte lesewis thei schulen be fed on the hillis of Israel.", "rotherham": "In good pastures, will I feed them, And on the mountains of the height of Israel, shall be their fold,— There, shall they lie down in a fold that is good, And on pasture that is fat, shall they feed. among the mountains of Israel.", "darby": "I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be: there shall they lie down in a good fold, and in a fat pasture they shall feed upon the mountains of Israel.", "twenty": "", "jps": "I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be; there shall they lie down in a good fold, and in a fat pasture shall they feed upon the mountains of Israel.", "acv": "I will feed them with good pasture, and their fold shall be upon the mountains of the height of Israel. There they shall lie down in a good fold, and on fat pasture they shall feed upon the mountains of Israel.", "anderson": "", "haweis": "", "noyes": "I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be; there shall they lie down in a good fold, and in a fat pasture shall they feed upon the mountains of Israel.", "webster": "I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be: there shall they lie in a good fold, and [in] a fat pasture shall they feed upon the mountains of Israel.", "vulgate": "in pascuis uberrimis pascam eas et in montibus excelsis Israhel erunt pascuae eorum ibi requiescent in herbis virentibus et in pascuis pinguibus pascentur super montes Israhel;", "brenton": "I will feed them in a good pasture, on a high mountain of Israel: and their folds shall be there, and they shall lie down, and there shall they rest in perfect prosperity, and they shall feed in a fat pasture on the mountains of Israel."}}, {"v": 15, "ref": "34:15", "o": "אֲנִ֨י אֶרְעֶ֤ה צֹאנִ/י֙ וַ/אֲנִ֣י אַרְבִּיצֵ֔/ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "I will feed my flock, and I will cause them to lie down, saith the Lord God.", "web": "I myself will be the shepherd of my sheep, and I will cause them to lie down, says the Lord Yahweh.", "bsb": "I will tend My flock and make them lie down, declares the Lord GOD.", "asv": "I myself will be the shepherd of my sheep, and I will cause them to lie down, saith the Lord Jehovah.", "ylt": "I feed My flock, and cause them to lie down, An affirmation of the Lord Jehovah.", "dra": "I will feed my sheep: and I will cause them to lie down, saith the Lord God.", "bbe": "I myself will give food to my flock, and I will give them rest, says the Lord.", "geneva": "I will feede my sheepe, and bring them to their rest, sayth the Lord God.", "wycliffe": "Y schal fede my scheep, and Y schal make hem to ligge, seith the Lord God.", "rotherham": "I myself, will tend my flock. And, I myself, will cause them to lie down, Declareth My Lord Yahweh:", "darby": "I will myself feed my flock, and I will cause them to lie down, saith the Lord Jehovah.", "twenty": "", "jps": "I will feed My sheep, and I will cause them to lie down, saith the L-rd GOD.", "acv": "I myself will be the shepherd of my sheep, and I will cause them to lie down, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "I will feed my flock, and I will cause them to lie down, saith the Lord Jehovah.", "webster": "I will feed my flock, and I will cause them to lie down, saith the Lord GOD.", "vulgate": "ego pascam oves meas et ego eas accubare faciam dicit Dominus Deus;", "brenton": "I will feed my sheep, and I will cause them to rest; and they shall know that I am the Lord: thus saith the Lord God."}}, {"v": 16, "ref": "34:16", "o": "אֶת הָ/אֹבֶ֤דֶת אֲבַקֵּשׁ֙ וְ/אֶת הַ/נִּדַּ֣חַת אָשִׁ֔יב וְ/לַ/נִּשְׁבֶּ֣רֶת אֶחֱבֹ֔שׁ וְ/אֶת הַ/חוֹלָ֖ה אֲחַזֵּ֑ק וְ/אֶת הַ/שְּׁמֵנָ֧ה וְ/אֶת הַ/חֲזָקָ֛ה אַשְׁמִ֖יד אֶרְעֶ֥/נָּה בְ/מִשְׁפָּֽט", "en": {"kjv": "I will seek that which was lost, and bring again that which was driven away, and will bind up that which was broken, and will strengthen that which was sick: but I will destroy the fat and the strong; I will feed them with judgment.", "web": "I will seek that which was lost, and will bring back that which was driven away, and will bind up that which was broken, and will strengthen that which was sick: but the fat and the strong I will destroy; I will feed them in justice.", "bsb": "I will seek the lost, bring back the strays, bind up the broken, and strengthen the weak; but the sleek and strong I will destroy. I will shepherd them with justice.’", "asv": "I will seek that which was lost, and will bring back that which was driven away, and will bind up that which was broken, and will strengthen that which was sick: but the fat and the strong I will destroy; I will feed them in justice.", "ylt": "The lost I seek, and the driven away bring back, And the broken I bind up, and the sick I strengthen, And the fat and the strong I destroy, I feed it with judgment.", "dra": "I will seek that which was lost: and that which was driven away, I will bring again: and I will bind up that which was broken, and I will strengthen that which was weak, and that which was fat and strong I will preserve, and I will feed them in judgment.", "bbe": "I will go in search of that which had gone wandering from the way, and will get back that which had been sent in flight, and will put bands on that which was broken, and give strength to that which was ill: but the fat and the strong I will give up to destruction; I will give them for their food the punishment which is theirs by right.", "geneva": "I will seeke that which was lost, and bring againe that which was driue away, and will binde vp that which was broken, and will strengthen the weake but I wil destroy the fat and the strong, and I will feede them with iudgement.", "wycliffe": "I schal seke that that perischide, and Y schal brynge ayen that that was cast awei; and Y schal bynde that that was brokun, and Y schal make sad that that was sijk; and Y schal kepe that that was fat and strong; and Y schal feede hem in doom;", "rotherham": "That which is straying, will I seek out. And that which hath been driven away, will I bring back, And that which is torn, will I bind up, And the weak, will I strengthen,- But the fat and the strong, will I watch I will feed them with justice.", "darby": "I will seek the lost, and bring again that which was driven away, and will bind up the broken, and will strengthen that which was sick; but I will destroy the fat and the strong: I will feed them with judgment.", "twenty": "", "jps": "I will seek that which was lost, and will bring back that which was driven away, and will bind up that which was broken, and will strengthen that which was sick; and the fat and the strong I will destroy, I will feed them in justice.", "acv": "I will seek that which was lost, and will bring back that which was driven away, and will bind up that which was broken, and will strengthen that which was sick, but I will destroy the fat and the strong. I will feed them in justice.", "anderson": "", "haweis": "", "noyes": "I will seek that which was lost, and bring back that which was driven away, and will bind up that which was broken, and will strengthen the sick; but the fat and the strong will I destroy; I will feed them as they deserve.", "webster": "I will seek that which was lost, and bring again that which was driven away, and will bind up [that which was] broken, and will strengthen that which was sick: but I will destroy the fat and the strong; I will feed them with judgment.", "vulgate": "quod perierat requiram et quod abiectum erat reducam et quod confractum fuerat alligabo et quod infirmum erat consolidabo et quod pingue et forte custodiam et pascam illas in iudicio;", "brenton": "I will seek that which is lost, and I will recover the stray one, and will bind up that which was broken, and will strengthen the fainting, and will guard the strong, and will feed them with judgment."}}, {"v": 17, "ref": "34:17", "o": "וְ/אַתֵּ֣נָה צֹאנִ֔/י כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הִנְ/נִ֤י שֹׁפֵט֙ בֵּֽין שֶׂ֣ה לָ/שֶׂ֔ה לָ/אֵילִ֖ים וְ/לָ/עַתּוּדִֽים", "en": {"kjv": "And as for you, O my flock, thus saith the Lord God; Behold, I judge between cattle and cattle, between the rams and the he goats.", "web": "As for you, O my flock, thus says the Lord Yahweh: Behold, I judge between sheep and sheep, the rams and the male goats.", "bsb": "This is what the Lord GOD says to you, My flock: ‘I will judge between one sheep and another, between the rams and the goats.", "asv": "And as for you, O my flock, thus saith the Lord Jehovah: Behold, I judge between sheep and sheep, the rams and the he-goats.", "ylt": "And you, My flock, thus said the Lord Jehovah: Lo, I am judging between sheep and sheep, Between rams and he-goats.", "dra": "And as for you, O my flocks, thus saith the Lord God: Behold I judge between cattle and cattle, of rams and of he goats.", "bbe": "And as for you, O my flock, says the Lord, truly, I will be judge between sheep and sheep, the he-sheep and the he-goats.", "geneva": "Also you my sheepe, Thus saieth the Lord God, behold, I iudge betweene sheepe, and sheepe, betweene the rammes and the goates.", "wycliffe": "forsothe ye ben my flockis. The Lord God seith these thingis, Lo! Y deme bitwixe beeste and beeste, and a wethir and a buc of geet.", "rotherham": "And as for you O my flock, Thus saith My Lord. Yahweh: Behold me! judging between one kind of small cattle and another as well the rams as the he-goats.", "darby": "And as for you, my flock, thus saith the Lord Jehovah: Behold, I judge between sheep and sheep, between the rams and the he-goats.", "twenty": "", "jps": "And as for you, O My flock, thus saith the L-rd GOD: Behold, I judge between cattle and cattle, even the rams and the he-goats.", "acv": "And as for you, O my flock, thus says the lord Jehovah: Behold, I judge between sheep and sheep, the rams and the he-goats.", "anderson": "", "haweis": "", "noyes": "And as for you, O my sheep, thus saith the Lord Jehovah: Behold, I will judge between the weak of the flock and the strong ones, even the rams and the he-goats.", "webster": "And [as for] you, O my flock, Thus saith the Lord GOD; Behold, I judge between cattle and cattle, between the rams and the he-goats.", "vulgate": "vos autem greges mei haec dicit Dominus Deus ecce ego iudico inter pecus et pecus arietum et hircorum;", "brenton": "And as for you, ye sheep, thus saith the Lord God, Behold, I will distinguish between sheep and sheep, between rams and he-goats."}}, {"v": 18, "ref": "34:18", "o": "הַ/מְעַ֣ט מִ/כֶּ֗ם הַ/מִּרְעֶ֤ה הַ/טּוֹב֙ תִּרְע֔וּ וְ/יֶ֨תֶר֙ מִרְעֵי/כֶ֔ם תִּרְמְס֖וּ בְּ/רַגְלֵי/כֶ֑ם וּ/מִשְׁקַע מַ֣יִם תִּשְׁתּ֔וּ וְ/אֵת֙ הַ/נּ֣וֹתָרִ֔ים בְּ/רַגְלֵי/כֶ֖ם תִּרְפֹּשֽׂוּ/ן", "en": {"kjv": "Seemeth it a small thing unto you to have eaten up the good pasture, but ye must tread down with your feet the residue of your pastures? and to have drunk of the deep waters, but ye must foul the residue with your feet?", "web": "Does it seem a small thing to you to have fed on the good pasture, but you must tread down with your feet the residue of your pasture? and to have drunk of the clear waters, but you must foul the residue with your feet?", "bsb": "Is it not enough for you to feed on the good pasture? Must you also trample the rest of the pasture with your feet? Is it not enough for you to drink the clear waters? Must you also muddy the rest with your feet?", "asv": "Seemeth it a small thing unto you to have fed upon the good pasture, but ye must tread down with your feet the residue of your pasture? and to have drunk of the clear waters, but ye must foul the residue with your feet?", "ylt": "Is it a little thing for you--the good pasture ye enjoy, And the remnant of your pasture ye tread down with your feet, And a depth of waters ye do drink, And the remainder with your feet ye trample,", "dra": "Was it not enough for you to feed upon good pastures? but you must also tread down with your feet the residue of your pastures: and when you drank the clearest water, you troubled the rest with your feet.", "bbe": "Does it seem a small thing to you to have taken your food on good grass-land while the rest of your grass-land is stamped down under your feet? and that after drinking from clear waters you make the rest of the waters dirty with your feet?", "geneva": "Seemeth it a small thing vnto you to haue eaten vp the good pasture, but yee must treade downe with your feete the residue of your pasture? and to haue drunke of the deepe waters, but yee must trouble the residue with your feete?", "wycliffe": "Whether it was not enowy to you to deuoure good pasturis? Ferthermore and ye defouliden with youre feet the remenauntis of youre lesewis, and whanne ye drunken clereste watir, ye disturbliden the residue with youre feet.", "rotherham": "Is it too small a thing for you that on the good pasture, ye feed, But the remainder of your pastures, ye must needs trample down with your feet? Or that of the pure waters, ye drink But the waters left remaining—with your feet, ye must needs foul?", "darby": "Is it too small a thing unto you to have eaten up the good pastures, but ye must tread down with your feet the rest of your pastures; and to have drunk of the settled waters, but ye must foul the rest with your feet?", "twenty": "", "jps": "Seemeth it a small thing unto you to have fed upon the good pasture, but ye must tread down with your feet the residue of your pasture? and to have drunk of the settled waters, but ye must foul the residue with your feet?", "acv": "Does it seem a small thing to you to have fed upon the good pasture, but ye must tread down with your feet the residue of your pasture, and to have drunk of the clear waters, but ye must foul the residue with your feet?", "anderson": "", "haweis": "", "noyes": "Seemeth it a small thing to you to eat up the good pasture, but ye must tread down with your feet the residue of your pastures? and to drink of the clear waters, but ye must foul the residue with your feet?", "webster": "[Seemeth it] a small thing to you to have eaten up the good pasture, but ye must tread down with your feet the residue of your pastures? and to have drank of the deep waters, but ye must foul the residue with your feet?", "vulgate": "nonne satis vobis erat pascuam bonam depasci insuper et reliquias pascuarum vestrarum conculcastis pedibus vestris et cum purissimam aquam biberetis reliquam pedibus vestris turbabatis;", "brenton": "And is it not enough for you that ye fed on the good pasture, that ye trampled with your feet the remnant of your pasture? and that ye drank the standing water, that ye disturbed the residue with your feet?"}}, {"v": 19, "ref": "34:19", "o": "וְ/צֹאנִ֑/י מִרְמַ֤ס רַגְלֵי/כֶם֙ תִּרְעֶ֔ינָה וּ/מִרְפַּ֥שׂ רַגְלֵי/כֶ֖ם תִּשְׁתֶּֽינָה", "en": {"kjv": "And as for my flock, they eat that which ye have trodden with your feet; and they drink that which ye have fouled with your feet.", "web": "As for my sheep, they eat that which you have trodden with your feet, and they drink that which you have fouled with your feet.", "bsb": "Why must My flock feed on what your feet have trampled, and drink what your feet have muddied?’", "asv": "And as for my sheep, they eat that which ye have trodden with your feet, and they drink that which ye have fouled with your feet.", "ylt": "And My flock the trodden thing of your feet consumeth, And the trampled thing of your feet drinketh?", "dra": "And my sheep were fed with that which you had trodden with your feet: and they drank what your feet had troubled.", "bbe": "And as for my sheep, their food is the grass which has been stamped on by your feet, and their drink the water which has been made dirty by your feet.", "geneva": "And my sheepe eate that which yee haue troden with your feete, and drinke that which ye haue troubled with your feete.", "wycliffe": "And my scheep weren fed with tho thingis that weren defoulid with youre feet; and thei drunken these thingis, that youre feet hadden troblid.", "rotherham": "And my flock On what hath been trampled down by your feet, may feed, And of what hath been fouled by your feet, may drink?", "darby": "And my sheep have to eat that which ye have trodden with your feet, and to drink that which ye have fouled with your feet.", "twenty": "", "jps": "And as for My sheep, they eat that which ye have trodden with your feet, and they drink that which ye have fouled with your feet.", "acv": "And as for my sheep, they eat that which ye have trodden with your feet, and they drink that which ye have fouled with your feet.", "anderson": "", "haweis": "", "noyes": "and that my sheep eat that which ye have trodden with your feet, and drink that which ye have fouled with your feet?", "webster": "And [as for] my flock, they eat that which ye have trodden with your feet; and they drink that which ye have fouled with your feet.", "vulgate": "et oves meae his quae conculcata pedibus vestris fuerant pascebantur et quae pedes vestri turbaverant haec bibebant;", "brenton": "So my sheep fed on that which ye had trampled with your feet; and they drank the water that had been disturbed by your feet."}}, {"v": 20, "ref": "34:20", "o": "לָ/כֵ֗ן כֹּ֥ה אָמַ֛ר אֲדֹנָ֥/י יְהוִ֖ה אֲלֵי/הֶ֑ם הִנְ/נִי אָ֕נִי וְ/שָֽׁפַטְתִּי֙ בֵּֽין שֶׂ֣ה בִרְיָ֔ה וּ/בֵ֥ין שֶׂ֖ה רָזָֽה", "en": {"kjv": "Therefore thus saith the Lord God unto them; Behold, I, even I, will judge between the fat cattle and between the lean cattle.", "web": "Therefore thus says the Lord Yahweh to them: Behold, I, even I, will judge between the fat sheep and the lean sheep.", "bsb": "Therefore this is what the Lord GOD says to them: ‘Behold, I Myself will judge between the fat sheep and the lean sheep.", "asv": "Therefore thus saith the Lord Jehovah unto them: Behold, I, even I, will judge between the fat sheep and the lean sheep.", "ylt": "Therefore, thus said the Lord Jehovah to them: Lo, I--even I, have judged between fat sheep and lean sheep.", "dra": "Therefore thus saith the Lord God to you: Behold, I myself will judge between the fat cattle and the lean.", "bbe": "For this reason the Lord has said to them, Truly, I, even I, will be judge between the fat sheep and the thin sheep.", "geneva": "Therefore thus sayth the Lord God vnto them, behold, I, euen I wil iudge betweene the fat sheepe and the leane sheepe.", "wycliffe": "Therfor the Lord God seith these thingis to you, Lo! Y my silf deme bitwixe a fat beeste and a leene beeste.", "rotherham": "Therefore Thus, saith My Lord Yahweh, unto them: Here am I myself. Therefore will I judge between fat sheep and lean sheep,", "darby": "Therefore thus saith the Lord Jehovah unto them: Behold, [it is] I, and I will judge between the fat sheep and the lean sheep.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD unto them: Behold, I, even I, will judge between the fat cattle and the lean cattle.", "acv": "Therefore thus says the lord Jehovah to them: Behold, I, even I, will judge between the fat sheep and the lean sheep.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah to them: Behold I, even I, will judge between the fat and the lean of the flock.", "webster": "Therefore thus saith the Lord GOD to them; Behold, I, even I, will judge between the fat cattle and between the lean cattle.", "vulgate": "propterea haec dicit Dominus Deus ad eos ecce ego ipse iudico inter pecus pingue et macilentum;", "brenton": "Therefore thus saith the Lord God; Behold, I will separate between the strong sheep and the weak sheep."}}, {"v": 21, "ref": "34:21", "o": "יַ֗עַן בְּ/צַ֤ד וּ/בְ/כָתֵף֙ תֶּהְדֹּ֔פוּ וּ/בְ/קַרְנֵי/כֶ֥ם תְּנַגְּח֖וּ כָּל הַ/נַּחְל֑וֹת עַ֣ד אֲשֶׁ֧ר הֲפִיצוֹתֶ֛ם אוֹתָ֖/נָה אֶל הַ/חֽוּצָ/ה", "en": {"kjv": "Because ye have thrust with side and with shoulder, and pushed all the diseased with your horns, till ye have scattered them abroad;", "web": "Because you thrust with side and with shoulder, and push all the diseased with your horns, until you have scattered them abroad;", "bsb": "Since you shove with flank and shoulder, butting all the weak ones with your horns until you have scattered them abroad,", "asv": "Because ye thrust with side and with shoulder, and push all the diseased with your horns, till ye have scattered them abroad;", "ylt": "Because with side and with shoulder ye thrust away, And with your horns push all the diseased, Till ye have scattered them to the out-place,", "dra": "Because you thrusted with sides and shoulders, and struck all the weak cattle with your horns, till they were scattered abroad:", "bbe": "Because you have been pushing with side and leg, pushing the diseased with your horns till they were sent away in every direction;", "geneva": "Because ye haue thrust with side and with shoulder, and pusht al the weake with your hornes, till ye haue scattered them abroade,", "wycliffe": "For that that ye hurliden with sidis, and schuldris, and wyndewiden with youre hornes alle sike beestis, til tho weren scaterid withoutforth, I schal saue my floc,", "rotherham": "Because with the side and with the shoulder, ye do thrust, And with your horns, ye do push all the sick,— Until you have scattered them abroad", "darby": "Because ye thrust with side and with shoulder, and push all the weak ones with your horns, till ye have scattered them abroad,", "twenty": "", "jps": "Because ye thrust with side and with shoulder, and push all the weak with your horns, till ye have scattered them abroad;", "acv": "Because ye thrust with side and with shoulder, and push all the diseased with your horns, till ye have scattered them abroad,", "anderson": "", "haweis": "", "noyes": "Because ye thrust with your side and with your shoulder, and push all the weak with your horns, till ye scatter them abroad,", "webster": "Because ye have thrust with side and with shoulder, and pushed all the diseased with your horns, till ye have scattered them abroad;", "vulgate": "pro eo quod lateribus et umeris inpingebatis et cornibus vestris ventilabatis omnia infirma pecora donec dispergerentur foras;", "brenton": "Ye did thrust with your sides and shoulders, and pushed with your horns, and ye cruelly treated all the sick."}}, {"v": 22, "ref": "34:22", "o": "וְ/הוֹשַׁעְתִּ֣י לְ/צֹאנִ֔/י וְ/לֹֽא תִהְיֶ֥ינָה ע֖וֹד לָ/בַ֑ז וְ/שָׁ֣פַטְתִּ֔י בֵּ֥ין שֶׂ֖ה לָ/שֶֽׂה", "en": {"kjv": "Therefore will I save my flock, and they shall no more be a prey; and I will judge between cattle and cattle.", "web": "therefore will I save my flock, and they shall no more be a prey; and I will judge between sheep and sheep.", "bsb": "I will save My flock, and they will no longer be prey. I will judge between one sheep and another.", "asv": "therefore will I save my flock, and they shall no more be a prey; and I will judge between sheep and sheep.", "ylt": "And I have given safety to My flock, And they are not any more for prey, And I have judged between sheep and sheep.", "dra": "I will save my flock, and it shall be no more a spoil, and I will judge between cattle and cattle.", "bbe": "I will make my flock safe, and they will no longer be taken away, and I will be judge between sheep and sheep.", "geneva": "Therefore wil I helpe my sheepe, and they shall no more be spoyled, and I wil iudge betweene sheepe and sheepe.", "wycliffe": "and it schal no more be in to raueyn. And Y schal deme bitwixe beeste and beeste;", "rotherham": "Therefore will I bring salvation to my flock, and they shall be no longer a prey,—but I will judge between one sheep and another,", "darby": "— I will save my flock, that they may no more be a prey; and I will judge between sheep and sheep.", "twenty": "", "jps": "therefore will I save My flock, and they shall no more be a prey; and I will judge between cattle and cattle.", "acv": "therefore I will save my flock, and they shall no more be a prey. And I will judge between sheep and sheep.", "anderson": "", "haweis": "", "noyes": "therefore will I save my sheep, and they shall no more be a prey; and I will judge between sheep and sheep.", "webster": "Therefore will I save my flock, and they shall no more be a prey; and I will judge between cattle and cattle.", "vulgate": "salvabo gregem meum et non erit ultra in rapinam et iudicabo inter pecus et pecus;", "brenton": "Therefore I will save my sheep, and they shall not be any more for a prey; and will judge between ram and ram."}}, {"v": 23, "ref": "34:23", "o": "וַ/הֲקִמֹתִ֨י עֲלֵי/הֶ֜ם רֹעֶ֤ה אֶחָד֙ וְ/רָעָ֣ה אֶתְ/הֶ֔ן אֵ֖ת עַבְדִּ֣/י דָוִ֑יד ה֚וּא יִרְעֶ֣ה אֹתָ֔/ם וְ/הֽוּא יִהְיֶ֥ה לָ/הֶ֖ן לְ/רֹעֶֽה", "en": {"kjv": "And I will set up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd.", "web": "I will set up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd.", "bsb": "I will appoint over them one shepherd, My servant David, and he will feed them. He will feed them and be their shepherd.", "asv": "And I will set up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd.", "ylt": "And have raised up over them one shepherd, And he hath fed them--my servant David, He doth feed them, and he is their shepherd,", "dra": "And I WILL SET UP ONE SHEPHERD OVER THEM, and he shall feed them, even my servant David: he shall feed them, and he shall be their shepherd.", "bbe": "And I will put over them one keeper, and he will give them food, even my servant David; he will give them food and be their keeper.", "geneva": "And I wil set vp a shepherd ouer them, and he shall feede them, euen my seruant Dauid, he shall feede them, and he shalbe their shepherd.", "wycliffe": "and Y schal reise on tho o sheepherde, my seruaunt Dauid, that schal fede tho; he schal fede tho, and he schal be `in to a sheepherde to hem.", "rotherham": "And I will raise up over them one shepherd And he shall tend them, Even my servant David,— He, will tend them, And, he, will become to them a shepherd;", "darby": "And I will set up one shepherd over them, and he shall feed them, even my servant David: he shall feed them, and he shall be their shepherd.", "twenty": "", "jps": "And I will set up one shepherd over them, and he shall feed them, even My servant David; he shall feed them, and he shall be their shepherd.", "acv": "And I will set up one shepherd over them, and he shall feed them, even my servant David. He shall feed them, and he shall be their shepherd.", "anderson": "", "haweis": "", "noyes": "And I will raise up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd.", "webster": "And I will set up one shepherd over them, and he shall feed them, [even] my servant David; he shall feed them, and he shall be their shepherd.", "vulgate": "et suscitabo super ea pastorem unum qui pascat ea servum meum David ipse pascet ea et ipse erit eis in pastorem;", "brenton": "And I will raise up one shepherd over them, and he shall tend them, even my servant David, and he shall be their shepherd;"}}, {"v": 24, "ref": "34:24", "o": "וַ/אֲנִ֣י יְהוָ֗ה אֶהְיֶ֤ה לָ/הֶם֙ לֵֽ/אלֹהִ֔ים וְ/עַבְדִּ֥/י דָוִ֖ד נָשִׂ֣יא בְ/תוֹכָ֑/ם אֲנִ֥י יְהוָ֖ה דִּבַּֽרְתִּי", "en": {"kjv": "And I the Lord will be their God, and my servant David a prince among them; I the Lord have spoken it.", "web": "I, Yahweh, will be their God, and my servant David prince among them; I, Yahweh, have spoken it.", "bsb": "I, the LORD, will be their God, and My servant David will be a prince among them. I, the LORD, have spoken.", "asv": "And I, Jehovah, will be their God, and my servant David prince among them; I, Jehovah, have spoken it.", "ylt": "And I, Jehovah, I am their God, And My servant David prince in their midst, I, Jehovah, have spoken.", "dra": "And I the Lord will be their God: and my servant David the prince in the midst of them: I the Lord have spoken it.", "bbe": "And I the Lord will be their God and my servant David their ruler; I the Lord have said it.", "geneva": "And I the Lord will be their God, and my seruant Dauid shalbe the prince amog them. I the Lord haue spoken it.", "wycliffe": "Forsothe Y the Lord schal be in to God to hem, and my seruaunt Dauid schal be prince in the myddis of hem; Y the Lord spak.", "rotherham": "And, I Yahweh, will become to them a God. my servant David, being a prince in their midst,— I Yahweh, have spoken;", "darby": "And I Jehovah will be theirGod, and my servant David a prince in their midst: I Jehovah have spoken [it].", "twenty": "", "jps": "And I HaShem will be their G-d, and My servant David prince among them; I HaShem have spoken.", "acv": "And I, Jehovah, will be their God, and my servant David ruler among them. I, Jehovah, have spoken it.", "anderson": "", "haweis": "", "noyes": "And I, Jehovah, will be their God, and my servant David a prince among them. I, Jehovah, have spoken it.", "webster": "And I the LORD will be their God, and my servant David a prince among them; I the LORD have spoken [it].", "vulgate": "ego autem Dominus ero eis in Deum et servus meus David princeps in medio eorum ego Dominus locutus sum;", "brenton": "and I the Lord will be to them a God, and David a prince in the midst of them; I the Lord have spoken it."}}, {"v": 25, "ref": "34:25", "o": "וְ/כָרַתִּ֤י לָ/הֶם֙ בְּרִ֣ית שָׁל֔וֹם וְ/הִשְׁבַּתִּ֥י חַיָּֽה רָעָ֖ה מִן הָ/אָ֑רֶץ וְ/יָשְׁב֤וּ בַ/מִּדְבָּר֙ לָ/בֶ֔טַח וְ/יָשְׁנ֖וּ בַּ/יְּעָרִֽים", "en": {"kjv": "And I will make with them a covenant of peace, and will cause the evil beasts to cease out of the land: and they shall dwell safely in the wilderness, and sleep in the woods.", "web": "I will make with them a covenant of peace, and will cause evil animals to cease out of the land; and they shall dwell securely in the wilderness, and sleep in the woods.", "bsb": "I will make with them a covenant of peace and rid the land of wild animals, so that they may dwell securely in the wilderness and sleep in the forest.", "asv": "And I will make with them a covenant of peace, and will cause evil beasts to cease out of the land; and they shall dwell securely in the wilderness, and sleep in the woods.", "ylt": "And I have made for them a covenant of peace, And caused evil beasts to cease out of the land, And they have dwelt in a wilderness confidently, And they have slept in forests.", "dra": "And I will make a covenant of peace with them, and will cause the evil beasts to cease out of the land: and they that dwell in the wilderness shall sleep secure in the forests.", "bbe": "And I will make with them an agreement of peace, and will put an end to evil beasts through all the land: and they will be living safely in the waste land, sleeping in the woods.", "geneva": "And I will make with them a couenant of peace, and will cause the euil beastes to cease out of the land: and they shall dwel safely in the wildernesse, and sleepe in the woods.", "wycliffe": "And Y schal make with hem a couenaunt of pees, and Y schal make worste beestis to ceesse fro erthe; and thei that dwellen in desert, schulen slepe sikur in forestis.", "rotherham": "And I will solemnise for them a covenant of prosperity, And will cause to cease the mischievous wild-beast out of the land, And they shall dwell in the wilderness, securely, And shall sleep in the forests;", "darby": "And I will make with them a covenant of peace, and will cause evil beasts to cease out of the land; and they shall dwell in safety in the wilderness, and sleep in the woods.", "twenty": "", "jps": "And I will make with them a covenant of peace, and will cause evil beasts to cease out of the land; and they shall dwell safely in the wilderness, and sleep in the woods.", "acv": "And I will make a covenant of peace with them, and will cause evil beasts to cease out of the land, and they shall dwell securely in the wilderness, and sleep in the woods.", "anderson": "", "haweis": "", "noyes": "And I will make with them a covenant of peace, and will cause evil beasts to cease out of the land, so that they shall dwell safely in the desert, and sleep in the woods.", "webster": "And I will make with them a covenant of peace, and will cause the evil beasts to cease out of the land: and they shall dwell safely in the wilderness, and sleep in the woods.", "vulgate": "et faciam cum eis pactum pacis et cessare faciam bestias pessimas de terra et qui habitant in deserto securi dormient in saltibus;", "brenton": "And I will make with David a covenant of peace and I will utterly destroy evil beasts from off the land; and they shall dwell in the wilderness, and sleep in the forests."}}, {"v": 26, "ref": "34:26", "o": "וְ/נָתַתִּ֥י אוֹתָ֛/ם וּ/סְבִיב֥וֹת גִּבְעָתִ֖/י בְּרָכָ֑ה וְ/הוֹרַדְתִּ֤י הַ/גֶּ֨שֶׁם֙ בְּ/עִתּ֔/וֹ גִּשְׁמֵ֥י בְרָכָ֖ה יִֽהְיֽוּ", "en": {"kjv": "And I will make them and the places round about my hill a blessing; and I will cause the shower to come down in his season; there shall be showers of blessing.", "web": "I will make them and the places around my hill a blessing; and I will cause the shower to come down in its season; there shall be showers of blessing.", "bsb": "I will make them and the places around My hill a blessing. I will send down showers in season—showers of blessing.", "asv": "And I will make them and the places round about my hill a blessing; and I will cause the shower to come down in its season; there shall be showers of blessing.", "ylt": "And I have given them, and the suburbs of my hill, a blessing, And caused the shower to come down in its season, Showers of blessing they are.", "dra": "And I will make them a blessing round about my hill: and I will send down the rain in its season, there shall be showers of blessing.", "bbe": "And I will give the rain at the right time, and I will make the shower come down at the right time; there will be showers of blessing.", "geneva": "And I wil set them, as a blessing, euen roud about my mountaine: and I will cause rayne to come downe in due season, and there shalbe raine of blessing.", "wycliffe": "And Y schal sette hem blessyng in the cumpas of my litle hil, and Y schal lede doun reyn in his tyme. And reynes of blessyng schulen be,", "rotherham": "And I, will make them and the places round about my hill a blessing,- And I will cause the abundant rain to come down in its season abundant rains of blessing, shall they be;", "darby": "And I will make them and the places round about my hill a blessing; and I will cause the shower to come down in its season: there shall be showers of blessing.", "twenty": "", "jps": "And I will make them and the places round about My hill a blessing; and I will cause the shower to come down in its season; there shall be showers of blessing.", "acv": "And I will make them and the places round about my hill a blessing, and I will cause the shower to come down in its season; there shall be showers of blessing.", "anderson": "", "haweis": "", "noyes": "And I will make them, and the places round about my hill, a blessing; and I will cause the shower to come down in its season; showers rich in blessings shall there be.", "webster": "And I will make them and the places around my hill a blessing; and I will cause the shower to come down in its season; there shall be showers of blessing.", "vulgate": "et ponam eos in circuitu collis mei benedictionem et deducam imbrem in tempore suo pluviae benedictionis erunt;", "brenton": "And I will settle them round about my mountain; and I will give you the rain, the rain of blessing."}}, {"v": 27, "ref": "34:27", "o": "וְ/נָתַן֩ עֵ֨ץ הַ/שָּׂדֶ֜ה אֶת פִּרְי֗/וֹ וְ/הָ/אָ֨רֶץ֙ תִּתֵּ֣ן יְבוּלָ֔/הּ וְ/הָי֥וּ עַל אַדְמָתָ֖/ם לָ/בֶ֑טַח וְֽ/יָדְע֞וּ כִּי אֲנִ֣י יְהוָ֗ה בְּ/שִׁבְרִ/י֙ אֶת מֹט֣וֹת עֻלָּ֔/ם וְ/הִ֨צַּלְתִּ֔י/ם מִ/יַּ֖ד הָ/עֹבְדִ֥ים בָּ/הֶֽם", "en": {"kjv": "And the tree of the field shall yield her fruit, and the earth shall yield her increase, and they shall be safe in their land, and shall know that I am the Lord, when I have broken the bands of their yoke, and delivered them out of the hand of those that served themselves of them.", "web": "The tree of the field shall yield its fruit, and the earth shall yield its increase, and they shall be secure in their land; and they shall know that I am Yahweh, when I have broken the bars of their yoke, and have delivered them out of the hand of those who made slaves of them.", "bsb": "The trees of the field will give their fruit, and the land will yield its produce; My flock will be secure in their land. Then they will know that I am the LORD, when I have broken the bars of their yoke and delivered them from the hands that enslaved them.", "asv": "And the tree of the field shall yield its fruit, and the earth shall yield its increase, and they shall be secure in their land; and they shall know that I am Jehovah, when I have broken the bars of their yoke, and have delivered them out of the hand of those that made bondmen of them.", "ylt": "And given hath the tree of the field its fruit, And the land doth give her increase, And they have been on their land confident, And they have known that I am Jehovah, In My breaking the bands of their yoke, And I have delivered them from the hand of those laying service on them.", "dra": "And the tree of the field shall yield its fruit, and the earth shall yield her increase, and they shall be in their land without fear: and they shall know that I am the Lord, when I shall have broken the bonds of their yoke, and shall have delivered them out of the hand of those that rule over them.", "bbe": "And the tree of the field will give its fruit and the earth will give its increase, and they will be safe in their land; and they will be certain that I am the Lord, when I have had their yoke broken and have given them salvation from the hands of those who made them servants.", "geneva": "And the tree of the fielde shall yeeld her fruite, and the earth shall giue her fruite, and they shalbe safe in their land, and shall know that I am the Lord, when I haue broken the cordes of their yoke, and deliuered them out of the hands of those that serued themselues of them.", "wycliffe": "and the tre of the feeld schal yyue his fruyt, and the erthe schal yyue his seed. And thei schulen be in her lond with out drede; and thei schulen wite, that Y am the Lord, whanne Y schal al to-breke the chaynes of her yok, and schal delyuere hem fro the hond of hem that comaunden to hem.", "rotherham": "And the tree of the field shall yield his fruit And, the land, shall yield her increase, And they shall remain on their own soil in security,- So shall they know that I, am Yahweh, When I have broken the bars of their yoke, And shall deliver them out of the hand of them who have been using them as slaves.", "darby": "And the tree of the field shall yield its fruit, and the earth shall yield its increase; and they shall be in safety in their land, and shall know that I [am] Jehovah, when I have broken the bands of their yoke and delivered them out of the hand of those that kept them in servitude.", "twenty": "", "jps": "And the tree of the field shall yield its fruit, and the earth shall yield her produce, and they shall be safe in their land; and they shall know that I am HaShem, when I have broken the bars of their yoke, and have delivered them out of the hand of those that made bondmen of them.", "acv": "And the tree of the field shall yield its fruit, and the earth shall yield its increase, and they shall be secure in their land. And they shall know that I am Jehovah when I have broken the bars of their yoke, and have delivered them out of the hand of those who made bondmen of them.", "anderson": "", "haweis": "", "noyes": "And the tree of the field shall yield her fruit, and the earth shall yield her increase; and they shall be secure in their land, and shall know that I am Jehovah, when I shall break the bands of their yoke and deliver them out of the hand of them that made them servants.", "webster": "And the tree of the field shall yield her fruit, and the earth shall yield her increase, and they shall be safe in their land, and shall know that I [am] the LORD, when I have broken the bands of their yoke, and delivered them out of the hand of those that subjected them to service.", "vulgate": "et dabit lignum agri fructum suum et terra dabit germen suum et erunt in terra sua absque timore et scient quia ego Dominus cum contrivero catenas iugi eorum et eruero eos de manu imperantium sibi;", "brenton": "And the trees that are in the field shall yield their fruit, and the earth shall yield her strength, and they shall dwell in the confidence of peace on their land, and they shall know that I am the Lord, when I have broken their yoke; and I will deliver them out of the hand of those that enslaved them."}}, {"v": 28, "ref": "34:28", "o": "וְ/לֹא יִהְי֨וּ ע֥וֹד בַּז֙ לַ/גּוֹיִ֔ם וְ/חַיַּ֥ת הָ/אָ֖רֶץ לֹ֣א תֹאכְלֵ֑/ם וְ/יָשְׁב֥וּ לָ/בֶ֖טַח וְ/אֵ֥ין מַחֲרִֽיד", "en": {"kjv": "And they shall no more be a prey to the heathen, neither shall the beast of the land devour them; but they shall dwell safely, and none shall make them afraid.", "web": "They shall no more be a prey to the nations, neither shall the animals of the earth devour them; but they shall dwell securely, and no one shall make them afraid.", "bsb": "They will no longer be prey for the nations, and the beasts of the earth will not consume them. They will dwell securely, and no one will frighten them.", "asv": "And they shall no more be a prey to the nations, neither shall the beasts of the earth devour them; but they shall dwell securely, and none shall make them afraid.", "ylt": "And they are no more a prey to nations, And the beast of the earth devoureth them not, And they have dwelt confidently, And there is none troubling.", "dra": "And they shall be no more for a spoil to the nations, neither shall the beasts of the earth devour them: but they shall dwell securely without, any terror.", "bbe": "And their goods will no longer be taken by the nations, and they will not again be food for the beasts of the earth; but they will be living safely and no one will be a cause of fear to them.", "geneva": "And they shall no more be spoyled of the heathen, neither shall the beastes of the land deuoure them, but they shall dwell safely and none shall make them afrayd.", "wycliffe": "And thei schulen no more be in to raueyn in to hethene men, nether the beestis of erthe schulen deuoure hem, but thei schulen dwelle tristili with outen ony drede.", "rotherham": "And they shall be no longer a prey for the nations, Nor shall the wild beast of the earth! devour them,— But they shall dwell securely with none to put them in terror.", "darby": "And they shall no more be a prey to the nations, neither shall the beast of the earth devour them; but they shall dwell in safety, and none shall make them afraid.", "twenty": "", "jps": "And they shall no more be a prey to the nations, neither shall the beast of the earth devour them; but they shall dwell safely, and none shall make them afraid.", "acv": "And they shall no more be a prey to the nations, nor shall the beasts of the earth devour them, but they shall dwell securely, and none shall make them afraid.", "anderson": "", "haweis": "", "noyes": "And they shall no more be a prey to the nations, neither shall the beasts of the land devour them; but they shall dwell in security, and none shall make them afraid.", "webster": "And they shall no more be a prey to the heathen, neither shall the beast of the land devour them; but they shall dwell safely, and none shall make [them] afraid.", "vulgate": "et non erunt ultra in rapinam gentibus neque bestiae terrae devorabunt eos sed habitabunt confidenter absque ullo terrore;", "brenton": "And they shall no more be a spoil to the nations, and the wild beasts of the land shall no more at all devour them; and they shall dwell safely, and there shall be none to make them afraid."}}, {"v": 29, "ref": "34:29", "o": "וַ/הֲקִמֹתִ֥י לָ/הֶ֛ם מַטָּ֖ע לְ/שֵׁ֑ם וְ/לֹֽא יִהְי֨וּ ע֜וֹד אֲסֻפֵ֤י רָעָב֙ בָּ/אָ֔רֶץ וְ/לֹֽא יִשְׂא֥וּ ע֖וֹד כְּלִמַּ֥ת הַ/גּוֹיִֽם", "en": {"kjv": "And I will raise up for them a plant of renown, and they shall be no more consumed with hunger in the land, neither bear the shame of the heathen any more.", "web": "I will raise up to them a plantation for renown, and they shall be no more consumed with famine in the land, neither bear the shame of the nations any more.", "bsb": "And I will raise up for them a garden of renown, and they will no longer be victims of famine in the land or bear the scorn of the nations.", "asv": "And I will raise up unto them a plantation for renown, and they shall be no more consumed with famine in the land, neither bear the shame of the nations any more.", "ylt": "And I have raised for them a plant for renown, And they are no more consumed by hunger in the land, And they bear no more the shame of the nations.", "dra": "And I will raise up for them a bud of renown: and they shall be no more consumed with famine in the land, neither shall they bear any more the reproach of the Gentiles.", "bbe": "And I will give them planting-places of peace, and they will no longer be wasted from need of food or put to shame by the nations.", "geneva": "And I will rayse vp for them a plant of renoume, and they shalbe no more consumed with hunger in the land, neither beare the reproche of the heathen any more.", "wycliffe": "And Y schal reise to hem a iust buriownyng named; and thei schulen no more be maad lesse for hunger in erthe, and thei schulen no more bere the schenschipis of hethene men.", "rotherham": "And I will raise up unto them a plantation for fame,- And there shall be no longer the destroyed of hunger in the land, Neither shall they bear any longer the reproach of the nations.", "darby": "And I will raise up for them a plant of renown, and they shall be no more consumed with hunger in the land, neither bear the ignominy of the nations any more.", "twenty": "", "jps": "And I will raise up unto them a plantation for renown, and they shall be no more consumed with hunger in the land, neither bear the shame of the nations any more.", "acv": "And I will raise up to them a plantation for renown, and they shall no more be consumed with famine in the land, nor bear the shame of the nations any more.", "anderson": "", "haweis": "", "noyes": "And I will raise up for them a plantation for my glory; and they shall no more be consumed with hunger in the land, neither shall they bear the reproach of the nations any more.", "webster": "And I will raise up for them a plant of renown, and they shall be no more consumed with hunger in the land, neither bear the shame of the heathen any more.", "vulgate": "et suscitabo eis germen nominatum et non erunt ultra inminuti fame in terra neque portabunt amplius obprobria gentium;", "brenton": "And I will raise up for them a plant of peace, and they shall no more perish with hunger upon the land, and they shall no more bear the reproach of the nations."}}, {"v": 30, "ref": "34:30", "o": "וְ/יָדְע֗וּ כִּ֣י אֲנִ֧י יְהוָ֛ה אֱלֹהֵי/הֶ֖ם אִתָּ֑/ם וְ/הֵ֗מָּה עַמִּ/י֙ בֵּ֣ית יִשְׂרָאֵ֔ל נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thus shall they know that I the Lord their God am with them, and that they, even the house of Israel, are my people, saith the Lord God.", "web": "They shall know that I, Yahweh, their God am with them, and that they, the house of Israel, are my people, says the Lord Yahweh.", "bsb": "Then they will know that I, the LORD their God, am with them, and that they, the house of Israel, are My people,’ declares the Lord GOD.", "asv": "And they shall know that I, Jehovah, their God am with them, and that they, the house of Israel, are my people, saith the Lord Jehovah.", "ylt": "And they have known that I, Jehovah, their God, am with them, And they--the house of Israel--My people, An affirmation of the Lord Jehovah.", "dra": "And they shall know that I the Lord their God am with them, and that they are my people the house of Israel: saith the Lord God.", "bbe": "And they will be certain that I the Lord their God am with them, and that they, the children of Israel, are my people, says the Lord.", "geneva": "Thus shall they vnderstande, that I the Lord their God am with them, and that they, euen the house of Israel, are my people, sayth the Lord God.", "wycliffe": "And thei schulen wite, that Y am her Lord God with hem, and thei ben my puple, the hous of Israel, seith the Lord God.", "rotherham": "So shall they know that, I, Yahweh their God am with them,- And that they are my people the house of Israel, Declareth My Lord. Yahweh.", "darby": "And they shall know that I Jehovah theirGod [am] with them, and that they, the house of Israel, are my people, saith the Lord Jehovah.", "twenty": "", "jps": "And they shall know that I HaShem their G-d am with them, and that they, the house of Israel, are My people, saith the L-rd GOD.", "acv": "And they shall know that I, Jehovah, their God am with them, and that they, the house of Israel, are my people, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Then shall they know, that I, Jehovah, their God, am with them, and that they, the house of Israel, are my people, saith the Lord Jehovah.", "webster": "Thus shall they know that I the LORD their God [am] with them, and [that] they, [even] the house of Israel, [are] my people, saith the Lord GOD.", "vulgate": "et scient quia ego Dominus Deus eorum cum eis et ipsi populus meus domus Israhel ait Dominus Deus;", "brenton": "And they shall know that I am the Lord their God, and they my people. O house of Israel, saith the Lord God,"}}, {"v": 31, "ref": "34:31", "o": "וְ/אַתֵּ֥ן צֹאנִ֛/י צֹ֥אן מַרְעִיתִ֖/י אָדָ֣ם אַתֶּ֑ם אֲנִי֙ אֱלֹ֣הֵי/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And ye my flock, the flock of my pasture, are men, and I am your God, saith the Lord God.", "web": "You my sheep, the sheep of my pasture, are men, and I am your God, says the Lord Yahweh.", "bsb": "‘You are My flock, the sheep of My pasture, My people, and I am your God,’ declares the Lord GOD.”", "asv": "And ye my sheep, the sheep of my pasture, are men, and I am your God, saith the Lord Jehovah.", "ylt": "And ye, My flock, the flock of My pasture, Men ye are --I am your God, An affirmation of the Lord Jehovah!'", "dra": "And you my flocks, the flocks of my pasture are men: and I am the Lord your God, saith the Lord God.", "bbe": "And you are my sheep, the sheep of my grass-lands, and I am your God, says the Lord.", "geneva": "And yee my sheepe, the sheepe of my pasture are men, and I am your God, saith the Lord God.", "wycliffe": "Forsothe ye my flockis ben men, the flockis of my lesewe; and Y am youre Lord God, seith the Lord God.", "rotherham": "Ye, therefore, my flock the flock of my pasture, are, men,— I, am your God, Declareth My Lord Yahweh.", "darby": "And ye, my flock, the flock of my pasture, are men: I [am] yourGod, saith the Lord Jehovah.", "twenty": "", "jps": "And ye My sheep, the sheep of My pasture, are men, and I am your G-d, saith the L-rd GOD.'", "acv": "And ye my sheep, the sheep of my pasture, are men, and I am your God, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "For ye, my flock, the flock of my pasture, are men, and I am your God, saith the Lord Jehovah.", "webster": "And ye my flock, the flock of my pasture, [are] men, [and] I [am] your God, saith the Lord GOD.", "vulgate": "vos autem greges mei greges pascuae meae homines estis et ego Dominus Deus vester dicit Dominus Deus;", "brenton": "ye are my sheep, even the sheep of my flock, and I am the Lord your God, saith the Lord God."}}]}, {"c": 35, "verses": [{"v": 1, "ref": "35:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Moreover, the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moveover the worde of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying,", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "35:2", "o": "בֶּן אָדָ֕ם שִׂ֥ים פָּנֶ֖י/ךָ עַל הַ֣ר שֵׂעִ֑יר וְ/הִנָּבֵ֖א עָלָֽי/ו", "en": {"kjv": "Son of man, set thy face against mount Seir, and prophesy against it,", "web": "Son of man, set your face against Mount Seir, and prophesy against it,", "bsb": "“Son of man, set your face against Mount Seir and prophesy against it,", "asv": "Son of man, set thy face against mount Seir, and prophesy against it,", "ylt": "`Son of man, set thy face against mount Seir, and prophesy against it,", "dra": "Son of man, set thy face against mount Seir, and prophesy concerning it, and say to it:", "bbe": "Son of man, let your face be turned to Mount Seir, and be a prophet against it,", "geneva": "Sonne of man, Set thy face against mount Seir, and prophesie against it,", "wycliffe": "and he seide, Thou, sone of man, sette thi face ayens the hil of Seir; and thou schalt profesie to it, and thou schalt seie to it,", "rotherham": "Son of man Set thy face against Mount Seir,—and prophesy against it;", "darby": "Son of man, set thy face against mount Seir, and prophesy against it,", "twenty": "", "jps": "'Son of man, set thy face against mount Seir, and prophesy against it,", "acv": "Son of man, set thy face against mount Seir, and prophesy against it.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against Mount Seir, and prophesy against it,", "webster": "Son of man, set thy face against mount Seir, and prophesy against it,", "vulgate": "fili hominis pone faciem tuam adversum montem Seir et prophetabis de eo et dices illi;", "brenton": "Son of man, set thy face against mount Seir, and prophesy against it,"}}, {"v": 3, "ref": "35:3", "o": "וְ/אָמַ֣רְתָּ לּ֗/וֹ כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֥י אֵלֶ֖י/ךָ הַר שֵׂעִ֑יר וְ/נָטִ֤יתִי יָדִ/י֙ עָלֶ֔י/ךָ וּ/נְתַתִּ֖י/ךָ שְׁמָמָ֥ה וּ/מְשַׁמָּֽה", "en": {"kjv": "And say unto it, Thus saith the Lord God; Behold, O mount Seir, I am against thee, and I will stretch out mine hand against thee, and I will make thee most desolate.", "web": "and tell it, Thus says the Lord Yahweh: Behold, I am against you, Mount Seir, and I will stretch out my hand against you, and I will make you a desolation and an astonishment.", "bsb": "and declare that this is what the Lord GOD says: Behold, I am against you, O Mount Seir. I will stretch out My hand against you and make you a desolate waste.", "asv": "and say unto it, Thus saith the Lord Jehovah: Behold, I am against thee, O mount Seir, and I will stretch out my hand against thee, and I will make thee a desolation and an astonishment.", "ylt": "and thou hast said to it: Thus said the Lord Jehovah: Lo, I am against thee, O mount Seir, And have stretched out My hand against thee, And made thee a desolation and an astonishment.", "dra": "Thus saith the Lord God: Behold I come against thee, mount Seir, and I will stretch forth my hand upon thee, and I will make thee desolate and waste.", "bbe": "And say to it, This is what the Lord has said: See, I am against you, O Mount Seir, and my hand will be stretched out against you, and I will make you a waste and a cause for wonder.", "geneva": "And say vnto it, Thus sayth the Lord God, Behold, O mount Seir, I come against thee, and I wil stretch out mine hand against thee, and I will make thee desolate and waste.", "wycliffe": "The Lord God seith these thingis, Thou hil of Seir, lo! Y to thee; Y schal stretche forth myn hond on thee, and Y schal yyue thee desolat and forsakun.", "rotherham": "and thou shalt say to it Thus saith My Lord Yahweh, Behold me! against thee Mount Seir,—Therefore will I stretch out my hand against thee, And I will make thee a desolation and an astonishment:", "darby": "and say unto it, Thus saith the Lord Jehovah: Behold, I am against thee, mount Seir, and I will stretch out my hand upon thee, and I will make thee a desolation and an astonishment.", "twenty": "", "jps": "and say unto it: Thus saith the L-rd GOD: Behold, I am against thee, O mount Seir, and I will stretch out My hand against thee, and I will make thee most desolate.", "acv": "And say to it, Thus says the lord Jehovah: Behold, I am against thee, O mount Seir, and I will stretch out my hand against thee, and I will make thee a desolation and an astonishment.", "anderson": "", "haweis": "", "noyes": "and say to it, Thus saith the Lord Jehovah: Behold, I am against thee, O Mount Seir, and I will stretch out my hand against thee, and I will make thee an utter desolation;", "webster": "And say to it, Thus saith the Lord GOD; Behold, O mount Seir, I [am] against thee, and I will stretch out my hand against thee, and I will make thee most desolate.", "vulgate": "haec dicit Dominus Deus ecce ego ad te mons Seir et extendam manum meam super te et dabo te desolatum atque desertum;", "brenton": "and say to it, Thus saith the Lord God; Behold, I am against thee, O mount Seir, and I will stretch out my hand against thee, and will make thee a waste, and thou shalt be made desolate."}}, {"v": 4, "ref": "35:4", "o": "עָרֶ֨י/ךָ֙ חָרְבָּ֣ה אָשִׂ֔ים וְ/אַתָּ֖ה שְׁמָמָ֣ה תִֽהְיֶ֑ה וְ/יָדַעְתָּ֖ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "I will lay thy cities waste, and thou shalt be desolate, and thou shalt know that I am the Lord.", "web": "I will lay your cities waste, and you shall be desolate; and you shall know that I am Yahweh.", "bsb": "I will turn your cities into ruins, and you will become a desolation. Then you will know that I am the LORD.", "asv": "I will lay thy cities waste, and thou shalt be desolate; and thou shalt know that I am Jehovah.", "ylt": "Thy cities a waste I make, and thou art a desolation, And thou hast known that I am Jehovah.", "dra": "I will destroy thy cities, and thou shalt be desolate: and thou shalt know that I am the Lord.", "bbe": "I will make your towns unpeopled and you will be a waste; and you will be certain that I am the Lord.", "geneva": "I wil lay thy cities waste, and thou shalt be desolate, and thou shalt knowe that I am the Lord.", "wycliffe": "Y schal distrie thi citees, and thou schalt be forsakun; and thou schalt wite, that Y am the Lord.", "rotherham": "Thy cities, will I lay waste, And thou—a desolation, shalt become, So shalt thou know that I, am Yahweh.", "darby": "I will lay thy cities waste, and thou shalt be a desolation: and thou shalt know that I [am] Jehovah.", "twenty": "", "jps": "I will lay thy cities waste, and thou shalt be desolate; and thou shalt know that I am HaShem.", "acv": "I will lay thy cities waste, and thou shall be desolate. And thou shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "I will lay thy cities waste, and thou shalt be desolate, and thou shalt know that I am Jehovah.", "webster": "I will lay thy cities waste, and thou shalt be desolate, and thou shalt know that I [am] the LORD.", "vulgate": "urbes tuas demoliar et tu desertus eris et scies quia ego Dominus;", "brenton": "And I will cause desolation in thy cities, and thou shalt be desolate, and thou shalt know that I am the Lord."}}, {"v": 5, "ref": "35:5", "o": "יַ֗עַן הֱי֤וֹת לְ/ךָ֙ אֵיבַ֣ת עוֹלָ֔ם וַ/תַּגֵּ֥ר אֶת בְּנֵֽי יִשְׂרָאֵ֖ל עַל יְדֵי חָ֑רֶב בְּ/עֵ֣ת אֵידָ֔/ם בְּ/עֵ֖ת עֲוֺ֥ן קֵֽץ", "en": {"kjv": "Because thou hast had a perpetual hatred, and hast shed the blood of the children of Israel by the force of the sword in the time of their calamity, in the time that their iniquity had an end:", "web": "Because you have had a perpetual hostility, and have given over the children of Israel to the power of the sword in the time of their calamity, in the time of the iniquity of the end;", "bsb": "Because you harbored an ancient hatred and delivered the Israelites over to the sword in the time of their disaster at the final stage of their punishment,", "asv": "Because thou hast had a perpetual enmity, and hast given over the children of Israel to the power of the sword in the time of their calamity, in the time of the iniquity of the end;", "ylt": "Because of thy having an enmity age-during, And thou dost saw the sons of Israel, By the hands of the sword, In the time of their calamity, In the time of the iniquity of the end:", "dra": "Because thou hast been an everlasting enemy, and hast shut up the children of Israel in the hands of the sword in the time of their affliction, in the time of their last iniquity.", "bbe": "Because yours has been a hate without end, and you have given up the children of Israel to the power of the sword in the time of their trouble, in the time of the punishment of the end:", "geneva": "Because thou hast had a perpetuall hatred and hast put the children of Israel to flight by the force of the sword in the time of their calamitie, when their iniquitie had an ende,", "wycliffe": "For thou were an enemye euerlastynge, and closidist togidere the sonis of Israel in to the hondis of swerd, in the tyme of her turment, in the tyme of the laste wickidnesse;", "rotherham": "Because thou hast had an age-abiding enmity, And hast delivered up the sons of Israel unto the hands of the sword,- In the time of their misfortune, In the time of the final punishment for iniquity,", "darby": "Because thou hast had a perpetual hatred, and hast given over the children of Israel to the power of the sword, in the time of their calamity, in the time of the iniquity of the end;", "twenty": "", "jps": "Because thou hast had a hatred of old, and hast hurled the children of Israel unto the power of the sword in the time of their calamity, in the time of the iniquity of the end;", "acv": "Because thou have had a perpetual enmity, and have given over the sons of Israel to the power of the sword in the time of their calamity, in the time of the iniquity of the end,", "anderson": "", "haweis": "", "noyes": "Because thou bearest a perpetual hatred, and deliverest up the sons of Israel to the sword in the time of their calamity, in the time when iniquity bringeth destruction:", "webster": "Because thou hast had a perpetual hatred, and hast shed [the blood of] the children of Israel by the force of the sword in the time of their calamity, in the time [that their] iniquity [had] an end:", "vulgate": "eo quod fueris inimicus sempiternus et concluseris filios Israhel in manus gladii in tempore adflictionis eorum in tempore iniquitatis extremae;", "brenton": "Because thou hast been a perpetual enemy, and hast laid wait craftily for the house of Israel, with the hand of enemies with a sword, in the time of injustice, at the last:"}}, {"v": 6, "ref": "35:6", "o": "לָ/כֵ֣ן חַי אָ֗נִי נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה כִּֽי לְ/דָ֥ם אֶעֶשְׂ/ךָ֖ וְ/דָ֣ם יִרְדֲּפֶ֑/ךָ אִם לֹ֥א דָ֛ם שָׂנֵ֖אתָ וְ/דָ֥ם יִרְדֲּפֶֽ/ךָ", "en": {"kjv": "Therefore, as I live, saith the Lord God, I will prepare thee unto blood, and blood shall pursue thee: sith thou hast not hated blood, even blood shall pursue thee.", "web": "therefore, as I live, says the Lord Yahweh, I will prepare you for blood, and blood shall pursue you: since you have not hated blood, therefore blood shall pursue you.", "bsb": "therefore as surely as I live, declares the Lord GOD, I will give you over to bloodshed and it will pursue you. Since you did not hate bloodshed, it will pursue you.", "asv": "therefore, as I live, saith the Lord Jehovah, I will prepare thee unto blood, and blood shall pursue thee: since thou hast not hated blood, therefore blood shall pursue thee.", "ylt": "Therefore, I live--an affirmation of the Lord Jehovah, Surely for blood I do appoint thee, And blood doth pursue thee, If blood thou hast not hated, Blood also doth pursue thee.", "dra": "Therefore as I live, saith the Lord God, I will deliver thee up to blood, and blood shall pursue thee: and whereas thou hast hated blood, blood shall pursue thee.", "bbe": "For this cause, by my life, says the Lord, because you have been sinning through blood, blood will come after you.", "geneva": "Therefore as I liue, sayth the Lord God, I wil prepare thee vnto blood, and blood shall pursue thee: except thou hate blood, euen blood shall pursue thee.", "wycliffe": "therfor Y lyue, seith the Lord God, for Y schal yyue thee to blood, and blood schal pursue thee; and sithen thou hatidist blood, blood schal pursue thee.", "rotherham": "Therefore, as I live, Declareth My Lord Yahweh, Surely regarding blood, will I deal with thee, Blood therefore, shall pursue thee,-Since blood thou hast not hated, Therefore blood, shall pursue thee,", "darby": "therefore, [as] I live, saith the Lord Jehovah, I will certainly appoint thee unto blood, and blood shall pursue thee; since thou hast not hated blood, blood shall pursue thee.", "twenty": "", "jps": "therefore, as I live, saith the L-rd GOD, I will prepare thee unto blood, and blood shall pursue thee; surely thou hast hated thine own blood, therefore blood shall pursue thee.", "acv": "therefore, as I live, says the lord Jehovah, I will prepare thee to blood, and blood shall pursue thee. Since thou have not hated blood, therefore blood shall pursue thee.", "anderson": "", "haweis": "", "noyes": "therefore, as I live, saith the Lord Jehovah, surely, to blood will I bring thee, and blood shall pursue thee; since thou hast not hated blood, blood shall pursue thee.", "webster": "Therefore, [as] I live, saith the Lord GOD, I will prepare thee to blood, and blood shall pursue thee: since thou hast not hated blood, even blood shall pursue thee.", "vulgate": "propterea vivo ego dicit Dominus Deus quoniam sanguini tradam te et sanguis te persequetur et cum sanguinem oderis sanguis persequetur te;", "brenton": "Therefore, as I live, saith the Lord God, verily thou hast sinned even to blood, therefore blood shall pursue thee."}}, {"v": 7, "ref": "35:7", "o": "וְ/נָֽתַתִּי֙ אֶת הַ֣ר שֵׂעִ֔יר לְ/שִֽׁמְמָ֖ה וּ/שְׁמָמָ֑ה וְ/הִכְרַתִּ֥י מִמֶּ֖/נּוּ עֹבֵ֥ר וָ/שָֽׁב", "en": {"kjv": "Thus will I make mount Seir most desolate, and cut off from it him that passeth out and him that returneth.", "web": "Thus will I make Mount Seir an astonishment and a desolation; and I will cut off from it him who passes through and him who returns.", "bsb": "I will make Mount Seir a desolate waste and will cut off from it those who come and go.", "asv": "Thus will I make mount Seir an astonishment and a desolation; and I will cut off from it him that passeth through and him that returneth.", "ylt": "And I have given mount Seir for a desolation and an astonishment, And have cut off from it him who is passing over and him who is returning,", "dra": "And I will make mount Seir waste and desolate: and I will take away from it him that goeth and him that returneth.", "bbe": "And I will make Mount Seir a cause for wonder and a waste, cutting off from it all comings and goings.", "geneva": "Thus will I make mount Seir desolate and waste, and cut off from it him that passeth out and him that returneth.", "wycliffe": "And Y schal yyue the hil of Seir desolat and forsakun, and Y schal take awei fro it a goere and a comere ayen;", "rotherham": "So then I will deliver up Mount Seir to desolation after desolation,- And will cut off therefrom him that passeth by and him that returneth,", "darby": "And I will make mount Seir a desolation and an astonishment, and cut off from it him that passeth out and him that returneth;", "twenty": "", "jps": "Thus will I make mount Seir most desolate, and cut off from it him that passeth through and him that returneth.", "acv": "Thus I will make mount Seir an astonishment and a desolation, and I will cut off from it him who passes through and him who returns.", "anderson": "", "haweis": "", "noyes": "Thus will I make Mount Seir an utter desolation, and cut off from it him that passeth out, and him that returneth.", "webster": "Thus will I make mount Seir most desolate, and cut off from it him that passeth out and him that returneth.", "vulgate": "et dabo montem Seir desolatum et desertum et auferam de eo euntem et redeuntem;", "brenton": "And I will make mount Seir a waste, and desolate, and I will destroy from off it men and cattle:"}}, {"v": 8, "ref": "35:8", "o": "וּ/מִלֵּאתִ֥י אֶת הָרָ֖י/ו חֲלָלָ֑י/ו גִּבְעוֹתֶ֤י/ךָ וְ/גֵאוֹתֶ֨י/ךָ֙ וְ/כָל אֲפִיקֶ֔י/ךָ חַלְלֵי חֶ֖רֶב יִפְּל֥וּ בָ/הֶֽם", "en": {"kjv": "And I will fill his mountains with his slain men: in thy hills, and in thy valleys, and in all thy rivers, shall they fall that are slain with the sword.", "web": "I will fill its mountains with its slain: in your hills and in your valleys and in all your watercourses shall they fall who are slain with the sword.", "bsb": "I will fill its mountains with the slain; those killed by the sword will fall on your hills, in your valleys, and in all your ravines.", "asv": "And I will fill its mountains with its slain: in thy hills and in thy valleys and in all thy watercourses shall they fall that are slain with the sword.", "ylt": "And filled his mountains with his wounded, Thy hills, and thy valleys, and all thy streams, The pierced of the sword fall into them.", "dra": "And I will fill his mountains with his men that are slain: in thy hills, and in thy valleys, and in thy torrents they shall fall that are slain with the sword.", "bbe": "I will make his mountains full of those who have been put to death; in your valleys and in all your water-streams men will be falling by the sword.", "geneva": "And I will fill his mountaines with his slayne men: in thine hilles, and in thy valleys and in all thy riuers shall they fall, that are slayne with the sworde.", "wycliffe": "and Y schal fille the hillis therof with the careyns of her slayn men. Men slayn by swerd schulen falle doun in thi litle hillis, and in thi valeys, and in thi strondis.", "rotherham": "And I will fill his mountains with his slain,— As for thy hills and thy hollows and all thy channels, they who are thrust through by the sword shall fall therein:", "darby": "and I will fill his mountains with his slain. In thy hills, and in thy valleys, and in all thy water-courses shall they fall that are slain with the sword.", "twenty": "", "jps": "And I will fill his mountains with his slain; in thy hills and in thy valleys and in all thy streams shall they fall that are slain with the sword.", "acv": "And I will fill its mountains with its slain. In thy hills and in thy valleys and in all thy watercourses they shall fall who are slain with the sword.", "anderson": "", "haweis": "", "noyes": "And I will fill his valleys with the slain. Upon thy hills and in thy plains and in thy valleys shall fall they that are slain with the sword.", "webster": "And I will fill his mountains with his slain [men]: in thy hills, and in thy valleys, and in all thy rivers, shall they fall that are slain with the sword.", "vulgate": "et implebo montes eius occisorum suorum in collibus tuis et in vallibus tuis atque in torrentibus interfecti gladio cadent;", "brenton": "and I will fill thy hills and thy valleys with slain men, and in all thy plains there shall fall in thee men slain with the sword."}}, {"v": 9, "ref": "35:9", "o": "שִֽׁמְמ֤וֹת עוֹלָם֙ אֶתֶּנְ/ךָ֔ וְ/עָרֶ֖י/ךָ לֹ֣א תישבנה תָשֹׁ֑בְנָה וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "I will make thee perpetual desolations, and thy cities shall not return: and ye shall know that I am the Lord.", "web": "I will make you a perpetual desolation, and your cities shall not be inhabited; and you shall know that I am Yahweh.", "bsb": "I will make you a perpetual desolation, and your cities will not be inhabited. Then you will know that I am the LORD.", "asv": "I will make thee a perpetual desolation, and thy cities shall not be inhabited; and ye shall know that I am Jehovah.", "ylt": "Desolations age-during I make thee, And thy cities do not return, And ye have known that I am Jehovah.", "dra": "I will make thee everlasting desolations, and thy cities shall not be inhabited: and thou shalt know that I am the Lord God.", "bbe": "I will make you waste for ever, and your towns will be unpeopled: and you will be certain that I am the Lord.", "geneva": "I wil make thee perpetual desolations, and thy cities shall not returne, and ye shall knowe that I am the Lord.", "wycliffe": "Y schal yyue thee in to euerlastynge wildirnessis, and thi citees schulen not be enhabitid; and ye schulen wite, that Y am the Lord God.", "rotherham": "Desolations age-abiding, will I make thee, And thy cities, shall not be inhabited,- So shall ye know that, I, am Yahweh.", "darby": "I will make thee perpetual desolations, and thy cities shall not be inhabited: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "I will make thee perpetual desolations, and thy cities shall not return; and ye shall know that I am HaShem.", "acv": "I will make thee a perpetual desolation, and thy cities shall not be inhabited. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "I will make thee a perpetual desolation, and thy cities shall not be inhabited; and ye shall know that I am Jehovah.", "webster": "I will make thee perpetual desolations, and thy cities shall not return: and ye shall know that I [am] the LORD.", "vulgate": "in solitudines sempiternas tradam te et civitates tuae non habitabuntur et scietis quoniam ego Dominus;", "brenton": "I will make thee a perpetual desolation, and thy cities shall not be inhabited any more: and thou shalt know that I am the Lord."}}, {"v": 10, "ref": "35:10", "o": "יַ֣עַן אֲ֠מָרְ/ךָ אֶת שְׁנֵ֨י הַ/גּוֹיִ֜ם וְ/אֶת שְׁתֵּ֧י הָ/אֲרָצ֛וֹת לִ֥/י תִהְיֶ֖ינָה וִֽ/ירַשְׁנ֑וּ/הָ וַֽ/יהוָ֖ה שָׁ֥ם הָיָֽה", "en": {"kjv": "Because thou hast said, These two nations and these two countries shall be mine, and we will possess it; whereas the Lord was there:", "web": "Because you have said, These two nations and these two countries shall be mine, and we will possess it; whereas Yahweh was there:", "bsb": "Because you have said, ‘These two nations and countries will be ours, and we will possess them,’ even though the LORD was there,", "asv": "Because thou hast said, These two nations and these two countries shall be mine, and we will possess it; whereas Jehovah was there:", "ylt": "Because of thy saying: The two nations and the two lands are mine, and we have possessed it, And Jehovah hath been there;", "dra": "Because thou hast said: The two nations, and the two lands shall be mine, and I will possess them by inheritance: whereas the Lord was there.", "bbe": "Because you have said, The two nations and the two countries are to be mine, and we will take them for our heritage; though the Lord was there:", "geneva": "Because thou hast said, These two nations, and these two countreys shalbe mine, and we wil possesse them (seeing the Lord was there)", "wycliffe": "For thou seidist, Twei folkis and twei londis schulen be myne, and Y schal welde tho bi eritage, whanne the Lord was there;", "rotherham": "Because thou hast said, the two nations, and the two lands, mine, shall become, that we may possess it Whereas Yahweh, had been there,", "darby": "Because thou hast said, These two nations and these two countries shall be mine, and we will possess it, whereas Jehovah was there:", "twenty": "", "jps": "Because thou hast said: These two nations and these two countries shall be mine, and we will possess it; whereas HaShem was there;", "acv": "Because thou have said, These two nations and these two countries shall be mine, and we will possess it, whereas Jehovah was there,", "anderson": "", "haweis": "", "noyes": "Because thou hast said, \"These two nations and these two countries shall be mine, and we shall possess them,\" whereas Jehovah was there;", "webster": "Because thou hast said, These two nations and these two countries shall be mine, and we will possess it; whereas the LORD was there:", "vulgate": "eo quod dixeris duae gentes et duae terrae meae erunt et hereditate possidebo eas cum Dominus esset ibi;", "brenton": "Because thou saidst, The two nations and the two countries shall be mine, and I shall inherit them; whereas the Lord is there:"}}, {"v": 11, "ref": "35:11", "o": "לָ/כֵ֣ן חַי אָ֗נִי נְאֻם֮ אֲדֹנָ֣/י יְהוִה֒ וְ/עָשִׂ֗יתִי כְּ/אַפְּ/ךָ֙ וּ/כְ/קִנְאָ֣תְ/ךָ֔ אֲשֶׁ֣ר עָשִׂ֔יתָה מִ/שִּׂנְאָתֶ֖י/ךָ בָּ֑/ם וְ/נוֹדַ֥עְתִּי בָ֖/ם כַּ/אֲשֶׁ֥ר אֶשְׁפְּטֶֽ/ךָ", "en": {"kjv": "Therefore, as I live, saith the Lord God, I will even do according to thine anger, and according to thine envy which thou hast used out of thy hatred against them; and I will make myself known among them, when I have judged thee.", "web": "therefore, as I live, says the Lord Yahweh, I will do according to your anger, and according to your envy which you have shown out of your hatred against them; and I will make myself known among them, when I shall judge you.", "bsb": "therefore as surely as I live, declares the Lord GOD, I will treat you according to the anger and jealousy you showed in your hatred against them, and I will make Myself known among them when I judge you.", "asv": "therefore, as I live, saith the Lord Jehovah, I will do according to thine anger, and according to thine envy which thou hast showed out of thy hatred against them; and I will make myself known among them, when I shall judge thee.", "ylt": "Therefore, I live--an affirmation of the Lord Jehovah, And I have done according to thine anger, And according to thine envy, With which thou hast wrought, Because of thy hatred against them, And I have been known among them when I judge thee.", "dra": "Therefore as I live, saith the Lord God, I will do according to thy wrath, and according to thy envy, which thou hast exercised in hatred to them: and I will be made known by them, when I shall have judged thee.", "bbe": "For this cause, by my life, says the Lord, I will do to you as you have done in your wrath and in your envy, which you have made clear in your hate for them; and I will make clear to you who I am when you are judged by me.", "geneva": "Therefore as I liue, sayth the Lord God, I wil euen do according to thy wrath, and according to thine indignation which thou hast vsed in thine hatred against them: and I wil make my selfe knowen among them whe I haue iudged thee.", "wycliffe": "therfor Y lyue, seith the Lord God, for Y schal do bi thi wraththe, and bi thin enuye, which thou didist, hatinge hem, and Y schal be made knowun bi hem, whanne Y schal deme thee;", "rotherham": "Therefore as I live, Declareth My Lord Yahweh, I will even deal according to thine anger, and according to thine envy, wherewith thou hast dealt, out of thy hatred with them,- So will I make myself known among them as soon as I shall judge thee", "darby": "therefore, [as] I live, saith the Lord Jehovah, I will even do according to thine anger and according to thine envy, as thou hast done out of thy hatred against them; and I will make myself known among them, when I shall judge thee.", "twenty": "", "jps": "therefore, as I live, saith the L-rd GOD, I will do according to thine anger and according to thine envy, which thou hast used out of thy hatred against them; and I will make Myself known among them, when I shall judge thee.", "acv": "therefore, as I live, says the lord Jehovah, I will do according to thine anger, and according to thine envy which thou have shown out of thy hatred against them. And I will make myself known among them when I shall judge thee.", "anderson": "", "haweis": "", "noyes": "therefore, as I live, saith the Lord Jehovah, I will do according to thine anger and according to thine envy which in thy hatred against them thou hast practised, and I will make myself known to them when I judge thee.", "webster": "Therefore, [as] I live, saith the Lord GOD, I will even do according to thy anger, and according to thy envy which thou hast used out of thy hatred against them; and I will make myself known among them, when I have judged thee.", "vulgate": "propterea vivo ego dicit Dominus Deus quia faciam iuxta iram tuam et secundum zelum tuum quem fecisti odio habens eos et notus efficiar per eos cum te iudicavero;", "brenton": "therefore, as I live, saith the Lord, I will even deal with thee according to thine enmity, and I will be made known to thee when I shall judge thee:"}}, {"v": 12, "ref": "35:12", "o": "וְֽ/יָדַעְתָּ֮ כִּֽי אֲנִ֣י יְהוָה֒ שָׁמַ֣עְתִּי אֶת כָּל נָאָֽצוֹתֶ֗י/ךָ אֲשֶׁ֥ר אָמַ֛רְתָּ עַל הָרֵ֥י יִשְׂרָאֵ֖ל לֵ/אמֹ֣ר שממה שָׁמֵ֑מוּ לָ֥/נוּ נִתְּנ֖וּ לְ/אָכְלָֽה", "en": {"kjv": "And thou shalt know that I am the Lord, and that I have heard all thy blasphemies which thou hast spoken against the mountains of Israel, saying, They are laid desolate, they are given us to consume.", "web": "You shall know that I, Yahweh, have heard all your insults which you have spoken against the mountains of Israel, saying, They are laid desolate, they have been given us to devour.", "bsb": "Then you will know that I, the LORD, have heard every contemptuous word you uttered against the mountains of Israel when you said, ‘They are desolate; they are given to us to devour!’", "asv": "And thou shalt know that I, Jehovah, have heard all thy revilings which thou hast spoken against the mountains of Israel, saying, They are laid desolate, they are given us to devour.", "ylt": "And thou hast known that I--Jehovah, I have heard all thy despisings that thou hast spoken Against mountains of Israel, saying: A desolation, to us they were given for food.", "dra": "And thou shalt know that I the Lord have heard all thy reproaches, that thou hast spoken against the mountains of Israel, saying. They are desolate, they are given to us to consume.", "bbe": "And you will see that I the Lord have had knowledge of all the bitter things which you have said against the mountains of Israel, saying, They have been made waste, they are given to us to take for our heritage.", "geneva": "And thou shalt know, that I the Lord haue heard all thy blasphemies which thou hast spoken against the mountaines of Israel, saying, They lye waste, they are giuen vs to be deuoured.", "wycliffe": "and thou schalt wite, that Y am the Lord. Y herde alle thi schenschipis, whiche thou spakist of the hillis of Israel, and seidist, The hillis of Israel ben forsakun, and ben youun to vs, for to deuoure.", "rotherham": "And thou shalt know that, I Yahweh, have heard all thy revilings which thou hast uttered against the mountains of Israel saying, They have become desolate,— To us, have they been given for food;", "darby": "And thou shalt know that I Jehovah have heard all thy reproaches, which thou hast uttered against the mountains of Israel, saying, They are laid desolate, they are given us to devour.", "twenty": "", "jps": "And thou shalt know that I HaShem have heard all thy blasphemies which thou hast spoken against the mountains of Israel, saying: They are laid desolate, they are given us to devour.", "acv": "And thou shall know that I, Jehovah, have heard all thy revilings which thou have spoken against the mountains of Israel, saying, They are laid desolate. They are given us to devour.", "anderson": "", "haweis": "", "noyes": "And thou shalt know that I am Jehovah, and that I have heard all thy blasphemies which thou hast spoken against the mountains of Israel, saying: \"They are laid desolate; to us are they given to be devoured.\"", "webster": "And thou shalt know that I [am] the LORD, [and that] I have heard all thy blasphemies which thou hast spoken against the mountains of Israel, saying, They are laid desolate, they are given us to consume.", "vulgate": "et scies quia ego Dominus audivi universa obprobria tua quae locutus es de montibus Israhel dicens deserti nobis dati sunt ad devorandum;", "brenton": "and thou shalt know that I am the Lord. I have heard the voice of thy blasphemies, whereas thou hast said, The desert mountains of Israel are given to us for food;"}}, {"v": 13, "ref": "35:13", "o": "וַ/תַּגְדִּ֤ילוּ עָלַ/י֙ בְּ/פִי/כֶ֔ם וְ/הַעְתַּרְתֶּ֥ם עָלַ֖/י דִּבְרֵי/כֶ֑ם אֲנִ֖י שָׁמָֽעְתִּי", "en": {"kjv": "Thus with your mouth ye have boasted against me, and have multiplied your words against me: I have heard them.", "web": "You have magnified yourselves against me with your mouth, and have multiplied your words against me: I have heard it.", "bsb": "You boasted against Me with your mouth and multiplied your words against Me. I heard it Myself!", "asv": "And ye have magnified yourselves against me with your mouth, and have multiplied your words against me: I have heard it.", "ylt": "And ye magnify yourselves against Me with your mouth, And have made abundant against Me your words, I--I have heard.", "dra": "And you rose up against me with your mouth, and have derogated from me by your words: I have heard them.", "bbe": "And you have made yourselves great against me with your mouths, increasing your words against me; and it has come to my ears.", "geneva": "Thus with your mouthes ye haue boasted against me, and haue multiplied your words against me: I haue heard them.", "wycliffe": "And ye han rise on me with youre mouth, and ye han deprauyd ayens me; Y herde youre wordis.", "rotherham": "And so ye have magnified yourselves against me with your mouth, And have caused to abound against me your words, —I, have heard!", "darby": "And ye have magnified yourselves against me with your mouth, and have multiplied your words against me: I have heard [them].", "twenty": "", "jps": "And ye have magnified yourselves against Me with your mouth, and have multiplied your words against Me; I have heard it.", "acv": "And ye have magnified yourselves against me with your mouth, and have multiplied your words against me. I have heard it.", "anderson": "", "haweis": "", "noyes": "Thus with your mouth have ye magnified yourselves against me, and multiplied your words against me; I have heard them.", "webster": "Thus with your mouth ye have boasted against me, and have multiplied your words against me: I have heard [them].", "vulgate": "et insurrexistis super me ore vestro et rogastis adversum me verba vestra ego audivi;", "brenton": "and thou hast spoken swelling words against me with thy mouth: I have heard them."}}, {"v": 14, "ref": "35:14", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה כִּ/שְׂמֹ֨חַ֙ כָּל הָ/אָ֔רֶץ שְׁמָמָ֖ה אֶעֱשֶׂה לָּֽ/ךְ", "en": {"kjv": "Thus saith the Lord God; When the whole earth rejoiceth, I will make thee desolate.", "web": "Thus says the Lord Yahweh: When the whole earth rejoices, I will make you desolate.", "bsb": "This is what the Lord GOD says: While the whole earth rejoices, I will make you desolate.", "asv": "Thus saith the Lord Jehovah: When the whole earth rejoiceth, I will make thee desolate.", "ylt": "Thus said the Lord Jehovah: According to the rejoicing of the whole land, A desolation I make of thee.", "dra": "Thus saith the Lord God: When the whole earth shall rejoice, I will make thee a wilderness.", "bbe": "This is what the Lord has said: Because you were glad over my land when it was a waste, so will I do to you:", "geneva": "Thus sayth the Lord God, So shall all the world reioyce when I shall make thee desolate.", "wycliffe": "The Lord God seith these thingis, While al the lond is glad, Y schal turne thee in to wildernesse.", "rotherham": "Thus, saith My Lord Yahweh,— When all the earth is rejoicing, a desolation, will I make thee:", "darby": "Thus saith the Lord Jehovah: When the whole earth rejoiceth, I will make thee a desolation.", "twenty": "", "jps": "Thus saith the L-rd GOD: When the whole earth rejoiceth, I will make thee desolate.", "acv": "Thus says the lord Jehovah: When the whole earth rejoices, I will make thee desolate.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: When the whole land rejoiceth, I will prepare desolation for thee.", "webster": "Thus saith the Lord GOD; When the whole earth rejoiceth, I will make thee desolate.", "vulgate": "haec dicit Dominus Deus laetante universa terra in solitudinem te redigam;", "brenton": "Thus saith the Lord; When all the earth is rejoicing, I will make thee desert."}}, {"v": 15, "ref": "35:15", "o": "כְּ/שִׂמְחָ֨תְ/ךָ֜ לְ/נַחְלַ֧ת בֵּֽית יִשְׂרָאֵ֛ל עַ֥ל אֲשֶׁר שָׁמֵ֖מָה כֵּ֣ן אֶעֱשֶׂה לָּ֑/ךְ שְׁמָמָ֨ה תִֽהְיֶ֤ה הַר שֵׂעִיר֙ וְ/כָל אֱד֣וֹם כֻּלָּ֔/הּ וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "As thou didst rejoice at the inheritance of the house of Israel, because it was desolate, so will I do unto thee: thou shalt be desolate, O mount Seir, and all Idumea, even all of it: and they shall know that I am the Lord.", "web": "As you rejoiced over the inheritance of the house of Israel, because it was desolate, so will I do to you: you shall be desolate, Mount Seir, and all Edom, even all of it; and they shall know that I am Yahweh.", "bsb": "As you rejoiced when the inheritance of the house of Israel became desolate, so will I do to you. You will become a desolation, O Mount Seir, and so will all of Edom. Then they will know that I am the LORD.", "asv": "As thou didst rejoice over the inheritance of the house of Israel, because it was desolate, so will I do unto thee: thou shalt be desolate, O mount Seir, and all Edom, even all of it; and they shall know that I am Jehovah.", "ylt": "According to thy joy at the inheritance of the house of Israel because of desolation, So I do to thee--a desolation thou art, O mount Seir, and all Edom--all of it, And they have known that I am Jehovah!", "dra": "As thou hast rejoiced over the inheritance of the house of Israel, because it was laid waste, so will I do to thee: thou shalt be laid waste, O mount Seir, and all Idumea: and they shall know that I am the Lord.", "bbe": "You will become a waste, O Mount Seir, and all Edom, even all of it: and you will be certain that I am the Lord.", "geneva": "As thou diddest reioyce at the inheritance of the house of Israel, because it was desolate, so will I doe vnto thee: thou shalt be desolate, O mount Seir, and all Idumea wholly, and they shall know, that I am the Lord.", "wycliffe": "As thou haddist ioie on the eritage of the hous of Israel, for it was distried, so Y schal do to thee; the hil of Seir schal be distried, and al Ydumee; and thei schulen wite, that Y am the Lord.", "rotherham": "As thou didst rejoice over the inheritance of the house of Israel because it had become a desolation, so, will, I, do unto thee,— A desolation, shalt thou become, O Mount Seir And all Edom all of it, So shall they know that, I, am Yahweh.", "darby": "As thou didst rejoice at the inheritance of the house of Israel, because it was desolated, so will I do unto thee: thou shalt be a desolation, O mount Seir, and all Edom, the whole of it: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "As thou didst rejoice over the inheritance of the house of Israel, because it was desolate, so will I do unto thee; thou shalt be desolate, O mount Seir, and all Edom, even all of it; and they shall know that I am HaShem.", "acv": "As thou rejoiced over the inheritance of the house of Israel, because it was desolate, so I will do to thee. Thou shall be desolate, O mount Seir, and all Edom, even all of it, and they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "As thou didst rejoice over my inheritance, the house of Israel, because it was desolate, so will I do to thee! Mount Seir shall be desolate, and all Edom, even all of it; and they shall know that I am Jehovah.", "webster": "As thou didst rejoice at the inheritance of the house of Israel, because it was desolate, so will I do to thee: thou shalt be desolate, O mount Seir, and all Edom, [even] all of it: and they shall know that I [am] the LORD.", "vulgate": "sicuti gavisus es super hereditatem domus Israhel eo quod fuerit dissipata sic faciam tibi dissipatus eris mons Seir et Idumea omnis et scient quia ego Dominus;", "brenton": "Thou shalt be desert, O mount Seir, and all Idumea; and it shall be utterly consumed: and thou shalt know that I am the Lord their God."}}]}, {"c": 36, "verses": [{"v": 1, "ref": "36:1", "o": "וְ/אַתָּ֣ה בֶן אָדָ֔ם הִנָּבֵ֖א אֶל הָרֵ֣י יִשְׂרָאֵ֑ל וְ/אָ֣מַרְתָּ֔ הָרֵי֙ יִשְׂרָאֵ֔ל שִׁמְע֖וּ דְּבַר יְהוָֽה", "en": {"kjv": "Also, thou son of man, prophesy unto the mountains of Israel, and say, Ye mountains of Israel, hear the word of the Lord:", "web": "You, son of man, prophesy to the mountains of Israel, and say, You mountains of Israel, hear Yahweh’s word.", "bsb": "“And you, son of man, prophesy to the mountains of Israel and say: O mountains of Israel, hear the word of the LORD.", "asv": "And thou, son of man, prophesy unto the mountains of Israel, and say, Ye mountains of Israel, hear the word of Jehovah.", "ylt": "And thou, son of man, prophesy unto mountains of Israel, and thou hast said, O mountains of Israel, hear a word of Jehovah.", "dra": "And thou son of man, prophesy to the mountains of Israel, and say: Ye mountains of Israel, hear the word of the Lord:", "bbe": "And you, son of man, be a prophet about the mountains of Israel, and say, You mountains of Israel, give ear to the word of the Lord:", "geneva": "Also thou sonne of man, prophesie vnto the mountaines of Israel, and say, Ye mountaines of Israel, heare the word of the Lord.", "wycliffe": "Forsothe thou, sone of man, profesie on the hillis of Israel; and thou schalt seie, Hillis of Israel, here ye the word of the Lord.", "rotherham": "Thou therefore. Son of man, Prophesy unto the mountains of Israel,—and thou shalt say, Ye mountains of Israel Hear ye the word of Yahweh.", "darby": "And thou, son of man, prophesy unto the mountains of Israel, and say, Mountains of Israel, hear the word of Jehovah.", "twenty": "", "jps": "And thou, son of man, prophesy unto the mountains of Israel, and say: Ye mountains of Israel, hear the word of HaShem.", "acv": "And thou, son of man, prophesy to the mountains of Israel, and say, Ye mountains of Israel, hear the word of Jehovah.", "anderson": "", "haweis": "", "noyes": "Also, thou son of man, prophesy to the mountains of Israel, and say: Ye mountains of Israel, hear the word of Jehovah.", "webster": "Also thou son of man, prophesy to the mountains of Israel, and say, Ye mountains of Israel, hear the word of the LORD:", "vulgate": "tu autem fili hominis propheta super montes Israhel et dices montes Israhel audite verbum Domini;", "brenton": "And thou, son of man, prophesy to the mountains of Israel, and say to the mountains of Israel, Hear ye the word of the Lord:"}}, {"v": 2, "ref": "36:2", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֣עַן אָמַ֧ר הָ/אוֹיֵ֛ב עֲלֵי/כֶ֖ם הֶאָ֑ח וּ/בָמ֣וֹת עוֹלָ֔ם לְ/מֽוֹרָשָׁ֖ה הָ֥יְתָה לָּֽ/נוּ", "en": {"kjv": "Thus saith the Lord God; Because the enemy hath said against you, Aha, even the ancient high places are ours in possession:", "web": "Thus says the Lord Yahweh: Because the enemy has said against you, Aha! and, The ancient high places are ours in possession;", "bsb": "This is what the Lord GOD says: Because the enemy has said of you, ‘Aha! The ancient heights have become our possession,’", "asv": "Thus saith the Lord Jehovah: Because the enemy hath said against you, Aha! and, The ancient high places are ours in possession;", "ylt": "Thus said the Lord Jehovah: Because the enemy said against you, Aha, and the high places of old for a possession have been to us,", "dra": "Thus saith the Lord God: Because the enemy hath said to you: Aha, the everlasting heights are given to us for an inheritance.", "bbe": "This is what the Lord has said: Because your hater has said against you, Aha! and, The old waste places are our heritage, we have taken them:", "geneva": "Thus saith the Lord God, because the enemie hath sayde against you, Aha, euen the hye places of the world are ours in possession,", "wycliffe": "The Lord God seith these thingis, For that that the enemy seide of you, Wel! euerlastyng hiynessis ben youun to vs in to eritage;", "rotherham": "Thus saith My Lord, Yahweh, Because the enemy hath said concerning you Aha! Even the high places of age-past times, for a possession have become ours", "darby": "Thus saith the Lord Jehovah: Because the enemy hath said against you, Aha! and, The ancient high places are become ours in possession;", "twenty": "", "jps": "Thus saith the L-rd GOD: Because the enemy hath said against you: Aha! even the ancient high places are ours in possession;", "acv": "Thus says the lord Jehovah: Because the enemy has said against you, Aha! and, The ancient high places are ours in possession,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because the enemy hath said concerning you, \"Aha! the everlasting heights have become our possession\";", "webster": "Thus saith the Lord GOD; Because the enemy had said against you, Aha, even the ancient high places are ours in possession:", "vulgate": "haec dicit Dominus Deus eo quod dixerit inimicus de vobis euge altitudines sempiternae in hereditatem datae sunt nobis;", "brenton": "Thus saith the Lord God; Because the enemy has said against you, Aha, the old waste places are become a possession for us:"}}, {"v": 3, "ref": "36:3", "o": "לָ/כֵן֙ הִנָּבֵ֣א וְ/אָמַרְתָּ֔ כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה יַ֣עַן בְּ/יַ֡עַן שַׁמּוֹת֩ וְ/שָׁאֹ֨ף אֶתְ/כֶ֜ם מִ/סָּבִ֗יב לִֽ/הְיוֹתְ/כֶ֤ם מֽוֹרָשָׁה֙ לִ/שְׁאֵרִ֣ית הַ/גּוֹיִ֔ם וַ/תֵּֽעֲל֛וּ עַל שְׂפַ֥ת לָשׁ֖וֹן וְ/דִבַּת עָֽם", "en": {"kjv": "Therefore prophesy and say, Thus saith the Lord God; Because they have made you desolate, and swallowed you up on every side, that ye might be a possession unto the residue of the heathen, and ye are taken up in the lips of talkers, and are an infamy of the people:", "web": "therefore prophesy, and say, Thus says the Lord Yahweh: Because, even because they have made you desolate, and swallowed you up on every side, that you might be a possession to the residue of the nations, and you are taken up in the lips of talkers, and the evil report of the people;", "bsb": "therefore prophesy and declare that this is what the Lord GOD says: Because they have made you desolate and have trampled you on every side, so that you became a possession of the rest of the nations and were taken up in slander by the lips of their talkers,", "asv": "therefore prophesy, and say, Thus saith the Lord Jehovah: Because, even because they have made you desolate, and swallowed you up on every side, that ye might be a possession unto the residue of the nations, and ye are taken up in the lips of talkers, and the evil report of the people;", "ylt": "therefore, prophesy, and thou hast said: Thus said the Lord Jehovah: Because, even because, of desolating, And of swallowing you up from round about, For your being a possession to the remnant of the nations, And ye are taken up on the tip of the tongue, And are an evil report of the people.", "dra": "Therefore prophesy, and say: Thus saith the Lord God: Because you have been desolate, and trodden under foot on every side, and made an inheritance to the rest of the nations, and are become the subject of the talk, and the reproach of the people:", "bbe": "For this cause be a prophet, and say, This is what the Lord has said: Because, even because they have been glad over you and put you to shame on every side, because you have become a heritage for the rest of the nations, and you are taken up on the lips of talkers and in the evil talk of the people:", "geneva": "Therefore prophesie, and say, Thus sayth the Lord God, Because that they haue made you desolate, and swallowed you vp on euery side, that ye might be a possession vnto the residue of the heathen, and ye are come vnto the lippes and tongues of men, and vnto the reproch of the people,", "wycliffe": "therefore profesie thou, and seie, The Lord God seith these thingis, For that that ye ben maad desolat, and defoulid bi cumpas, and ben maad in to eritage to othere folkis, and ye stieden on the lippe of tunge, and on the schenschipe of puple;", "rotherham": "Therefore, prophesy, and thou shalt say, Thus saith My Lord Yahweh-Because even because they have desolated and panted for you on every side That ye should become a possession to the rest of the nations, And ye have come up into the talk of the tongue and the slander of the people", "darby": "therefore prophesy and say, Thus saith the Lord Jehovah: Because, yea, because they have made [you] desolate, and have swallowed you up on every side, that ye might be a possession unto the remnant of the nations, and ye are taken up in the lips of talkers, and in the defaming of the people:", "twenty": "", "jps": "therefore prophesy, and say: Thus saith the L-rd GOD: Because, even because they have made you desolate, and swallowed you up on every side, that ye might be a possession unto the rest of the nations, and ye are taken up in the lips of talkers, and the evil report of the people;", "acv": "therefore prophesy, and say, Thus says the lord Jehovah: Because, even because they have made you desolate, and swallowed you up on every side, that ye might be a possession to the residue of the nations, and ye are taken up in the lips of talkers, and the evil report of the people,", "anderson": "", "haweis": "", "noyes": "therefore prophesy and say, Thus saith the Lord Jehovah: Because, yea, because they have made you desolate, and swallowed you up on every side, so that ye have become a possession to the residue of the nations, and a subject for the lips of talkers, and a derision to the people;", "webster": "Therefore prophesy and say, Thus saith the Lord GOD; Because they have made [you] desolate, and swallowed you up on every side, that ye might be a possession to the residue of the heathen, and ye are taken up in the lips of talkers, and [are] an infamy of the people:", "vulgate": "propterea vaticinare et dic haec dicit Dominus Deus pro eo quod desolati estis et conculcati per circuitum et facti in hereditatem reliquis gentibus et ascendistis super labium linguae et obprobrium populi;", "brenton": "therefore prophesy, and say, Thus saith the Lord God; Because ye have been dishonoured, and hated by those round about you, that ye might be a possession to the remainder of the nations, and ye became a by-word, and a reproach to the nations:"}}, {"v": 4, "ref": "36:4", "o": "לָ/כֵן֙ הָרֵ֣י יִשְׂרָאֵ֔ל שִׁמְע֖וּ דְּבַר אֲדֹנָ֣/י יְהוִ֑ה כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְ֠הוִה לֶ/הָרִ֨ים וְ/לַ/גְּבָע֜וֹת לָ/אֲפִיקִ֣ים וְ/לַ/גֵּאָי֗וֹת וְ/לֶ/חֳרָב֤וֹת הַ/שֹּֽׁמְמוֹת֙ וְ/לֶ/עָרִ֣ים הַ/נֶּעֱזָב֔וֹת אֲשֶׁ֨ר הָי֤וּ לְ/בַז֙ וּ/לְ/לַ֔עַג לִ/שְׁאֵרִ֥ית הַ/גּוֹיִ֖ם אֲשֶׁ֥ר מִ/סָּבִֽיב", "en": {"kjv": "Therefore, ye mountains of Israel, hear the word of the Lord God; Thus saith the Lord God to the mountains, and to the hills, to the rivers, and to the valleys, to the desolate wastes, and to the cities that are forsaken, which became a prey and derision to the residue of the heathen that are round about;", "web": "therefore, you mountains of Israel, hear the word of the Lord Yahweh: Thus says the Lord Yahweh to the mountains and to the hills, to the watercourses and to the valleys, to the desolate wastes and to the cities that are forsaken, which are become a prey and derision to the residue of the nations that are all around;", "bsb": "therefore, O mountains of Israel, hear the word of the Lord GOD. This is what the Lord GOD says to the mountains and hills, to the ravines and valleys, to the desolate ruins and abandoned cities, which have become a spoil and a mockery to the rest of the nations around you.", "asv": "therefore, ye mountains of Israel, hear the word of the Lord Jehovah: Thus saith the Lord Jehovah to the mountains and to the hills, to the watercourses and to the valleys, to the desolate wastes and to the cities that are forsaken, which are become a prey and derision to the residue of the nations that are round about;", "ylt": "Therefore, O mountains of Israel, Hear a word of the Lord Jehovah: Thus said the Lord Jehovah, to mountains, and to hills, To streams, and to valleys, And to wastes that are desolate, And to cities that are forsaken, That have been for a prey, And for a scorn, to the remnant of the nations who are round about.", "dra": "Therefore, ye mountains of Israel, hear the word of the Lord God: Thus saith the Lord God to the mountains, and to the hills, to the brooks, and to the valleys, and to desolate places, and ruinous walls, and to the cities that are forsaken, that are spoiled, and derided by the rest of the nations round about.", "bbe": "For this reason, you mountains of Israel, give ear to the word of the Lord; this is what the Lord has said to the mountains and to the hills, to the streams and to the valleys, to the unpeopled wastes and to the towns where no one is living, from which the goods have been taken and which have been put to shame by the rest of the nations who are round about:", "geneva": "Therefore ye mountaines of Israel, heare the worde of the Lord God, Thus sayth the Lord God to the mountaines and to the hilles, to the riuers, and to the valleys, and to the waste, and desolate places, and to the cities that are forsaken: which are spoyled and had in derision of the residue of the heathen that are round about.", "wycliffe": "therfor, hillis of Israel, here ye the word of the Lord God. The Lord God seith these thingis to the mounteyns, and litle hillis, to strondis, and to valeis, and to peecis of wallis left, and to citees forsakun, that ben maad bare of puplis, and ben scorned of othere folkis bi cumpas;", "rotherham": "Therefore ye mountains of Israel, hear ye the word of My Lord Yahweh,— Thus saith My Lord, Yahweh, To the mountains and to the hills, to the channels and to the valleys, and to the desolate waste places and to the cities that are forsaken, which have become a prey and a derision, to the rest of the nations which are on every side:", "darby": "therefore, ye mountains of Israel, hear the word of the Lord Jehovah. Thus saith the Lord Jehovah to the mountains and to the hills, to the water-courses and to the valleys, to the desolate wastes and to the cities that are forsaken, which are become a prey and a derision to the remnant of the nations that are round about,", "twenty": "", "jps": "therefore, ye mountains of Israel, hear the word of the L-rd GOD: Thus saith the L-rd GOD to the mountains and to the hills, to the streams and to the valleys, to the desolate wastes and to the cities that are forsaken, which are become a prey and derision to the residue of the nations that are round about;", "acv": "therefore, ye mountains of Israel, hear the word of the lord Jehovah. Thus says the lord Jehovah to the mountains and to the hills, to the watercourses and to the valleys, to the desolate wastes and to the cities that are forsaken, which have become a prey and derision to the residue of the nations that are round about,", "anderson": "", "haweis": "", "noyes": "therefore, ye mountains of Israel, hear the word of the Lord Jehovah. Thus saith the Lord Jehovah, to the mountains and the hills, the valleys and the plain, to the desolate wastes and to the forsaken cities, which are become a prey and a derision to the residue of the nations which are round about,—", "webster": "Therefore, ye mountains of Israel, hear the word of the Lord GOD; Thus saith the Lord GOD to the mountains, and to the hills, to the rivers, and to the valleys, to the desolate wastes, and to the cities that are forsaken, which became a prey and derision to the residue of the heathen that [are] around;", "vulgate": "propterea montes Israhel audite verbum Domini Dei haec dicit Dominus Deus montibus et collibus torrentibus vallibusque et desertis parietinis et urbibus derelictis quae depopulatae sunt et subsannatae a reliquis gentibus per circuitum;", "brenton": "therefore, ye mountains of Israel, hear the word of the Lord; Thus saith the Lord to the mountains, and to the hills, and to the streams, and to the valleys, and to the places that have been made desolate and destroyed, and to the cities that have been deserted, and have become a spoil and a trampling to the nations that were left round about;"}}, {"v": 5, "ref": "36:5", "o": "לָ/כֵ֗ן כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ אִם לֹ֠א בְּ/אֵ֨שׁ קִנְאָתִ֥/י דִבַּ֛רְתִּי עַל שְׁאֵרִ֥ית הַ/גּוֹיִ֖ם וְ/עַל אֱד֣וֹם כֻּלָּ֑/א אֲשֶׁ֣ר נָתְנֽוּ אֶת אַרְצִ֣/י לָ֠/הֶם לְ/מ֨וֹרָשָׁ֜ה בְּ/שִׂמְחַ֤ת כָּל לֵבָב֙ בִּ/שְׁאָ֣ט נֶ֔פֶשׁ לְמַ֥עַן מִגְרָשָׁ֖/הּ לָ/בַֽז", "en": {"kjv": "Therefore thus saith the Lord God; Surely in the fire of my jealousy have I spoken against the residue of the heathen, and against all Idumea, which have appointed my land into their possession with the joy of all their heart, with despiteful minds, to cast it out for a prey.", "web": "therefore thus says the Lord Yahweh: Surely in the fire of my jealousy have I spoken against the residue of the nations, and against all Edom, that have appointed my land to themselves for a possession with the joy of all their heart, with despite of soul, to cast it out for a prey.", "bsb": "Therefore this is what the Lord GOD says: Surely in My burning zeal I have spoken against the rest of the nations, and against all Edom, who took My land as their own possession with wholehearted joy and utter contempt, so that its pastureland became plunder.", "asv": "therefore thus saith the Lord Jehovah: Surely in the fire of my jealousy have I spoken against the residue of the nations, and against all Edom, that have appointed my land unto themselves for a possession with the joy of all their heart, with despite of soul, to cast it out for a prey.", "ylt": "Therefore, thus said the Lord Jehovah: Have I not, in the fire of My jealousy, Spoken against the remnant of the nations, And against Edom--all of it, Who gave My land to themselves for a possession, With the joy of the whole heart--with despite of soul, For the sake of casting it out for a prey?", "dra": "Therefore thus saith the Lord God: In the fire of my zeal I have spoken of the rest of the nations, and of all Edom, who have taken my land to themselves, for an inheritance with joy, and with all the heart, and with the mind: and have cast it out to lay it waste.", "bbe": "For this cause the Lord has said: Truly, in the heat of my bitter feeling I have said things against the rest of the nations and against all Edom, who have taken my land as a heritage for themselves with the joy of all their heart, and with bitter envy of soul have made attacks on it:", "geneva": "Therefore thus saith the Lord God, Surely in the fire of mine indignation haue I spoken against the residue of the heathen, and against all Idumea, which haue taken my lande for their possession, with the ioy of all their heart, and with despitefull mindes to cast it out for a pray.", "wycliffe": "therfore the Lord God seith these thingis, For in the fier of my feruour Y spak of othere folkis, and of al Idumee, that yauen my lond in to eritage to hem silf with ioie `and al herte, and of entent, and castiden out it, to distrie it; therfor profesie thou on the erthe of Israel,", "rotherham": "Therefore, Thus, saith My Lord, Yahweh, Surely in the fire of my jealousy, have I spoken against the rest of the nations and against Edom all of it,— Who have given my land to themselves for a possession, In the rejoicing of all the heart In contempt of soul, To make of its produce a prey.", "darby": "— therefore thus saith the Lord Jehovah: Surely in the fire of my jealousy have I spoken against the remnant of the nations, and against the whole of Edom, which have appointed my land unto themselves for a possession with the joy of all [their] heart, with despite of soul, to plunder it by pillage.", "twenty": "", "jps": "therefore thus saith the L-rd GOD: Surely in the fire of My jealousy have I spoken against the residue of the nations, and against all Edom, that have appointed My land unto themselves for a possession with the joy of all their heart, with disdain of soul, to cast it out for a prey;", "acv": "therefore thus says the lord Jehovah: Surely in the fire of my jealousy I have spoken against the residue of the nations, and against all Edom, who have appointed my land to themselves for a possession with the joy of all their heart, with spite of soul, to cast it out for a prey.", "anderson": "", "haweis": "", "noyes": "therefore thus saith the Lord Jehovah: Surely in the fire of my jealousy have I spoken against the residue of the nations, and against all Edom, who have allotted my land to themselves for a possession, with joy of their whole heart, and with a despiteful mind, to cast it out for a prey.", "webster": "Therefore thus saith the Lord GOD; Surely in the fire of my jealousy have I spoken against the residue of the heathen, and against all Edom, who have appointed my land into their possession with the joy of all [their] heart, with despiteful minds, to cast it out for a prey.", "vulgate": "propterea haec dicit Dominus Deus quoniam in igne zeli mei locutus sum de reliquis gentibus et de Idumea universa qui dederunt terram meam sibi in hereditatem cum gaudio et toto corde ex animo et eiecerunt eam ut vastarent;", "brenton": "therefore, thus saith the Lord; Verily in the fire of my wrath have I spoken against the rest of the nations, and against all Idumea, because they have appropriated my land to themselves for a possession with joy, disregarding the lives of the inhabitants, to destroy it by plunder:"}}, {"v": 6, "ref": "36:6", "o": "לָ/כֵ֕ן הִנָּבֵ֖א עַל אַדְמַ֣ת יִשְׂרָאֵ֑ל וְ/אָמַרְתָּ֡ לֶ/הָרִ֣ים וְ֠/לַ/גְּבָעוֹת לָ/אֲפִיקִ֨ים וְ/לַ/גֵּאָי֜וֹת כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הִנְ/נִ֨י בְ/קִנְאָתִ֤/י וּ/בַ/חֲמָתִ/י֙ דִּבַּ֔רְתִּי יַ֛עַן כְּלִמַּ֥ת גּוֹיִ֖ם נְשָׂאתֶֽם", "en": {"kjv": "Prophesy therefore concerning the land of Israel, and say unto the mountains, and to the hills, to the rivers, and to the valleys, Thus saith the Lord God; Behold, I have spoken in my jealousy and in my fury, because ye have borne the shame of the heathen:", "web": "Therefore prophesy concerning the land of Israel, and tell the mountains and to the hills, to the watercourses and to the valleys, Thus says the Lord Yahweh: Behold, I have spoken in my jealousy and in my wrath, because you have borne the shame of the nations:", "bsb": "Therefore, prophesy concerning the land of Israel and tell the mountains and hills, the ravines and valleys, that this is what the Lord GOD says: Behold, I have spoken in My burning zeal because you have endured the reproach of the nations.", "asv": "Therefore prophesy concerning the land of Israel, and say unto the mountains and to the hills, to the watercourses and to the valleys, Thus saith the Lord Jehovah: Behold, I have spoken in my jealousy and in my wrath, because ye have borne the shame of the nations:", "ylt": "Therefore, prophesy concerning the ground of Israel, And thou hast said to mountains, and to hills, To streams, and to valleys, Thus said the Lord Jehovah: Lo, I, in My jealousy, and in My fury, I have spoken, Because the shame of nations ye have borne.", "dra": "Prophesy therefore concerning the land of Israel, and say to the mountains, and to the hills, to the ridges, and to the valleys: Thus saith the Lord God: Behold I have spoken in my zeal, and in my indignation, because you have borne the shame of the Gentiles.", "bbe": "For this cause be a prophet about the land of Israel, and say to the mountains and to the hills, to the streams and to the valleys, This is what the Lord has said: Truly, in my bitter feeling and in my wrath I have said these things, because you have undergone the shame of the nations:", "geneva": "Prophesie therfore vpon the land of Israel, and say vnto the mountaines, and to the hilles, to the riuers, and to the valleys, Thus sayth the Lord God, Behold, I haue spoken in mine indignation, and in my wrath, because yee haue suffered the shame of the heathen,", "wycliffe": "and thou schalt seie to mounteyns, and litle hillis, to the hiynesse of hillis, and to valeis, The Lord God seith these thingis, For that that ye ben desolat, lo! Y spak in my feruour and in my strong veniaunce. For that that ye suffriden schenschipe of hethene men;", "rotherham": "Therefore prophesy, concerning the soil of Israel,—and say to the mountains and to the hills to the channels and to the valleys, Thus, saith My Lord Yahweh, Behold me! In my jealousy and in mine indignation, have I spoken, Because the insult of the nations, ye have borne;", "darby": "Prophesy therefore concerning the land of Israel, and say to the mountains and to the hills, to the water-courses and to the valleys, Thus saith the Lord Jehovah: Behold, I have spoken in my jealousy and in my fury, because ye have borne the ignominy of the nations;", "twenty": "", "jps": "therefore prophesy concerning the land of Israel, and say unto the mountains and to the hills, to the streams and to the valleys: Thus saith the L-rd GOD: Behold, I have spoken in My jealousy and in My fury, because ye have borne the shame of the nations;", "acv": "Therefore prophesy concerning the land of Israel, and say to the mountains and to the hills, to the watercourses and to the valleys, Thus says the lord Jehovah: Behold, I have spoken in my jealousy and in my wrath, because ye have borne the shame of the nations.", "anderson": "", "haweis": "", "noyes": "Prophesy, therefore, concerning the land of Israel, and say to the mountains and to the hills, to the valleys and the plains, Thus saith the Lord Jehovah: Behold, I have spoken in my jealousy and in my fury, because ye have borne the reproach of the nations.", "webster": "Prophesy therefore concerning the land of Israel, and say to the mountains, and to the hills, to the rivers, and to the valleys, Thus saith the Lord GOD; Behold, I have spoken in my jealousy and in my fury, because ye have borne the shame of the heathen:", "vulgate": "idcirco vaticinare super humum Israhel et dices montibus et collibus iugis et vallibus haec dicit Dominus Deus ecce ego in zelo meo et in furore meo locutus sum eo quod confusionem gentium sustinueritis;", "brenton": "therefore prophesy concerning the land of Israel, and say to the mountains, and to the hills, and to the valleys, and to the forests, Thus saith the Lord; Behold, I have spoken in my jealousy and in my wrath, because ye have borne the reproaches of the heathen:"}}, {"v": 7, "ref": "36:7", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה אֲנִ֖י נָשָׂ֣אתִי אֶת יָדִ֑/י אִם לֹ֤א הַ/גּוֹיִם֙ אֲשֶׁ֣ר לָ/כֶ֣ם מִ/סָּבִ֔יב הֵ֖מָּה כְּלִמָּתָ֥/ם יִשָּֽׂאוּ", "en": {"kjv": "Therefore thus saith the Lord God; I have lifted up mine hand, Surely the heathen that are about you, they shall bear their shame.", "web": "therefore thus says the Lord Yahweh: I have sworn, Surely the nations that are around you, they shall bear their shame.", "bsb": "Therefore this is what the Lord GOD says: I have sworn with an uplifted hand that surely the nations around you will endure reproach of their own.", "asv": "therefore thus saith the Lord Jehovah: I have sworn, saying, Surely the nations that are round about you, they shall bear their shame.", "ylt": "Therefore, thus said the Lord Jehovah: I--I have lifted up My hand, Do not--the nations who are with you from round about--they their own shame bear?", "dra": "Therefore thus saith the Lord God: I have lifted up my hand, that the Gentiles who are round about you, shall themselves bear their shame.", "bbe": "For this cause the Lord has said, See, I have taken an oath that the nations which are round about you are themselves to undergo the shame which they have put on you.", "geneva": "Therefore thus saith the Lord God, I haue lifted vp mine hand, surely the heathen that are about you, shall beare their shame.", "wycliffe": "therfor the Lord God seith these thingis, Lo! Y reiside myn hond ayens hethene men, that ben in youre cumpas, that thei bere her schenschipe.", "rotherham": "Therefore Thus saith My Lord Yahweh, I myself have lifted my hand,- Surely the nations which are yours round about, they their own shame, shall bear:", "darby": "therefore thus saith the Lord Jehovah: I have lifted up my hand, [saying,] Verily the nations that are about you, they shall bear their shame.", "twenty": "", "jps": "therefore thus saith the L-rd GOD: I have lifted up My hand: Surely the nations that are round about you, they shall bear their shame.", "acv": "Therefore thus says the lord Jehovah: I have sworn, saying, Surely the nations that are round about you, they shall bear their shame.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: I have lifted up my hand, that the nations that are round about you, that they shall bear their reproach.", "webster": "Therefore thus saith the Lord GOD; I have lifted up my hand, Surely the heathen that [are] about you, they shall bear their shame.", "vulgate": "idcirco haec dicit Dominus Deus ego levavi manum meam ut gentes quae in circuitu vestro sunt ipsae confusionem suam portent;", "brenton": "therefore I will lift up my hand against the nations that are round about you; they shall bear their reproach."}}, {"v": 8, "ref": "36:8", "o": "וְ/אַתֶּ֞ם הָרֵ֤י יִשְׂרָאֵל֙ עַנְפְּ/כֶ֣ם תִּתֵּ֔נוּ וּ/פֶרְיְ/כֶ֥ם תִּשְׂא֖וּ לְ/עַמִּ֣/י יִשְׂרָאֵ֑ל כִּ֥י קֵרְב֖וּ לָ/בֽוֹא", "en": {"kjv": "But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to my people of Israel; for they are at hand to come.", "web": "But you, mountains of Israel, you shall shoot out your branches, and yield your fruit to my people Israel; for they are at hand to come.", "bsb": "But you, O mountains of Israel, will produce branches and bear fruit for My people Israel, for they will soon come home.", "asv": "But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to my people Israel; for they are at hand to come.", "ylt": "And ye, O mountains of Israel, Your branch ye give out, and your fruits ye bear for My people Israel, For they have drawn near to come.", "dra": "But as for you, O mountains of Israel, shoot ye forth your branches, and yield your fruit to my people of Israel: for they are at hand to come.", "bbe": "But you, O mountains of Israel, will put out your branches and give your fruit to my people Israel; for they are ready to come.", "geneva": "But you, O mountaines of Israel, yee shall shoote forth your branches, and bring foorth your fruite to my people of Israel: for they are ready to come.", "wycliffe": "Forsothe, ye hillis of Israel, brynge forth youre braunchis, and bringe ye fruit to my puple Israel; for it is niy that it come.", "rotherham": "But ye O mountains of Israel Your boughs, shall ye shoot forth, And your fruit, shall ye bear For my people Israel, For they have drawn near to enter.", "darby": "And ye mountains of Israel shall shoot forth your branches, and yield your fruit to my people Israel: for they are at hand to come.", "twenty": "", "jps": "But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to My people Israel; for they are at hand to come.", "acv": "But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to my people Israel, for they are at hand to come.", "anderson": "", "haweis": "", "noyes": "But ye, O mountains of Israel, shall shoot forth your branches, and bear your fruit for my people Israel; for they are near coming.", "webster": "But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to my people of Israel; for they are at hand to come.", "vulgate": "vos autem montes Israhel ramos vestros germinetis et fructum vestrum adferatis populo meo Israhel prope est enim ut veniat;", "brenton": "But your grapes and your fruits, O mountains of Israel, shall my people eat; for they are hoping to come."}}, {"v": 9, "ref": "36:9", "o": "כִּ֖י הִנְ/נִ֣י אֲלֵי/כֶ֑ם וּ/פָנִ֣יתִי אֲלֵי/כֶ֔ם וְ/נֶעֱבַדְתֶּ֖ם וְ/נִזְרַעְתֶּֽם", "en": {"kjv": "For, behold, I am for you, and I will turn unto you, and ye shall be tilled and sown:", "web": "For, behold, I am for you, and I will turn into you, and you shall be tilled and sown;", "bsb": "For behold, I am on your side; I will turn toward you, and you will be tilled and sown.", "asv": "For, behold, I am for you, and I will turn unto you, and ye shall be tilled and sown;", "ylt": "For, lo, I am for you, and have turned to you, And ye have been tilled and sown.", "dra": "For I, I am for you, and I will turn to you, and you shall be ploughed and sown.", "bbe": "For truly I am for you, and I will be turned to you, and you will be ploughed and planted:", "geneva": "For behold, I come vnto you, and I wil turne vnto you, and ye shalbe tilled and sowen.", "wycliffe": "For lo! Y to you, and Y schal turne to you, and ye schulen be erid, and schulen take seed.", "rotherham": "For lo! I am towards you, Therefore will I turn towards you, And ye shall be tilled and sown;", "darby": "For behold, I am for you, and I will turn unto you, and ye shall be tilled and sown.", "twenty": "", "jps": "For, behold, I am for you, and I will turn unto you, and ye shall be tilled and sown;", "acv": "For, behold, I am for you, and I will turn into you, and ye shall be tilled and sown.", "anderson": "", "haweis": "", "noyes": "For behold, I am for you, and I will turn to you, and ye shall be tilled and sown;", "webster": "For behold, I [am] for you, and I will turn to you, and ye shall be tilled and sown:", "vulgate": "quia ecce ego ad vos et convertar ad vos et arabimini et accipietis sementem;", "brenton": "For, behold, I am toward you, and I will have respect to you, and ye shall be tilled and sown:"}}, {"v": 10, "ref": "36:10", "o": "וְ/הִרְבֵּיתִ֤י עֲלֵי/כֶם֙ אָדָ֔ם כָּל בֵּ֥ית יִשְׂרָאֵ֖ל כֻּלֹּ֑/ה וְ/נֹֽשְׁבוּ֙ הֶֽ/עָרִ֔ים וְ/הֶ/חֳרָב֖וֹת תִּבָּנֶֽינָה", "en": {"kjv": "And I will multiply men upon you, all the house of Israel, even all of it: and the cities shall be inhabited, and the wastes shall be builded:", "web": "and I will multiply men on you, all the house of Israel, even all of it; and the cities shall be inhabited, and the waste places shall be built;", "bsb": "I will multiply the people upon you—the house of Israel in its entirety. The cities will be inhabited and the ruins rebuilt.", "asv": "and I will multiply men upon you, all the house of Israel, even all of it; and the cities shall be inhabited, and the waste places shall be builded;", "ylt": "And I have multiplied on you men, All the house of Israel--all of it, And the cities have been inhabited, And the wastes are built.", "dra": "And I will multiply men upon you, and all the house of Israel: and the cities ball be inhabited, and the ruinous places shall be repaired.", "bbe": "And I will let your numbers be increased, all the children of Israel, even all of them: and the towns will be peopled and the waste places will have buildings;", "geneva": "And I wil multiply the men vpon you, euen all the house of Israel wholly, and the cities shalbe inhabited, and the desolate places shalbe builded.", "wycliffe": "And in you I schal multiplie men, and al the hous of Israel; and citees schulen be enhabitid, and ruynouse thingis schulen be reparelid.", "rotherham": "And I will multiply, upon you—men, All the house of Israel All of it, Then shall the cities be inhabited, And the waste places, shall be built,", "darby": "And I will multiply men upon you, all the house of Israel, the whole of it; and the cities shall be inhabited, and the waste places shall be builded.", "twenty": "", "jps": "and I will multiply men upon you, all the house of Israel, even all of it; and the cities shall be inhabited, and the waste places shall be builded;", "acv": "And I will multiply men upon you, all the house of Israel, even all of it, and the cities shall be inhabited, and the waste places shall be built.", "anderson": "", "haweis": "", "noyes": "and I will multiply men upon you, even all the house of Israel, all of it; and the cities shall be inhabited, and the waste places shall be built.", "webster": "And I will multiply men upon you, all the house of Israel, [even] all of it: and the cities shall be inhabited, and the wastes shall be built.", "vulgate": "et multiplicabo in vobis homines omnemque domum Israhel et habitabuntur civitates et ruinosa instaurabuntur;", "brenton": "and I will multiply men upon you, even all the house of Israel to the end: and the cities shall be inhabited, and the desolate land shall be built upon."}}, {"v": 11, "ref": "36:11", "o": "וְ/הִרְבֵּיתִ֧י עֲלֵי/כֶ֛ם אָדָ֥ם וּ/בְהֵמָ֖ה וְ/רָב֣וּ וּ/פָר֑וּ וְ/הוֹשַׁבְתִּ֨י אֶתְ/כֶ֜ם כְּ/קַדְמֽוֹתֵי/כֶ֗ם וְ/הֵטִֽבֹתִי֙ מֵ/רִאשֹׁ֣תֵי/כֶ֔ם וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will multiply upon you man and beast; and they shall increase and bring fruit: and I will settle you after your old estates, and will do better unto you than at your beginnings: and ye shall know that I am the Lord.", "web": "and I will multiply on you man and animal; and they shall increase and be fruitful; and I will cause you to be inhabited after your former estate, and you will do better than at your beginnings: and you shall know that I am Yahweh.", "bsb": "I will fill you with people and animals, and they will multiply and be fruitful. I will make you as inhabited as you once were, and I will make you prosper more than before. Then you will know that I am the LORD.", "asv": "and I will multiply upon you man and beast; and they shall increase and be fruitful; and I will cause you to be inhabited after your former estate, and will do better unto you than at your beginnings: and ye shall know that I am Jehovah.", "ylt": "And I have multiplied on you man and beast, And they have multiplied and been fruitful, And I have caused you to dwell according to your former states, And I have done better than at your beginnings, And ye have known that I am Jehovah.", "dra": "And I will make you abound with men and with beasts: and they shall be multiplied, and increased: and I will settle you as from the beginning, and will give you greater gifts, than you had from the beginning: and you shall know that I am the Lord.", "bbe": "Man and beast will be increased in you, and they will have offspring and be fertile: I will make you thickly peopled as you were before, and will do more for you than at the first: and you will be certain that I am the Lord.", "geneva": "And I wil multiply vpon you man and beast, and they shall encrease, and bring fruite, and I will cause you to dwell after your olde estate, and I will bestowe benefites vpon you more then at the first, and ye shall know that I am the Lord.", "wycliffe": "And Y schal fille you with men and beestis, and thei schulen be multiplied, and schulen encreesse; and Y schal make you to dwelle as at the bigynnyng, and Y schal rewarde with more goodis than ye hadden at the bigynnyng; and ye schulen wite, that Y am the Lord.", "rotherham": "And I will multiply upon you—man and beast, And they shall multiply and be fruitful,— And I will cause you to be inhabited as in your former estates. And will do you more good than at your beginnings, So shall ye know that am Yahweh;", "darby": "And I will multiply upon you man and beast, and they shall increase and bring forth fruit; and I will cause you to be inhabited as [in] your former times, yea, I will make it better than at your beginnings: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "and I will multiply upon you man and beast, and they shall increase and be fruitful; and I will cause you to be inhabited after your former estate, and will do better unto you than at your beginnings; and ye shall know that I am HaShem.", "acv": "And I will multiply upon you man and beast, and they shall increase and be fruitful. And I will cause you to be inhabited according to your former estate, and will do better to you than at your beginnings. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "I will multiply men upon you, and beasts; and they shall increase and be fruitful; and I will cause you to be inhabited as of old, and will do better to you than in the ancient time; and ye shall know that I am Jehovah.", "webster": "And I will multiply upon you man and beast; and they shall increase and bring fruit: and I will settle you after your old states, and will do better [to you] than at your beginnings: and ye shall know that I [am] the LORD.", "vulgate": "et replebo vos hominibus et iumentis et multiplicabuntur et crescent et habitari vos faciam sicut a principio bonisque donabo maioribus quam habuistis ab initio et scietis quia ego Dominus;", "brenton": "And I will multiply men and cattle upon you; and I will cause you to dwell as at the beginning, and will treat you well, as in your former times: and ye shall know that I am the Lord."}}, {"v": 12, "ref": "36:12", "o": "וְ/הוֹלַכְתִּי֩ עֲלֵי/כֶ֨ם אָדָ֜ם אֶת עַמִּ֤/י יִשְׂרָאֵל֙ וִֽ/ירֵשׁ֔וּ/ךָ וְ/הָיִ֥יתָ לָ/הֶ֖ם לְ/נַחֲלָ֑ה וְ/לֹא תוֹסִ֥ף ע֖וֹד לְ/שַׁכְּלָֽ/ם", "en": {"kjv": "Yea, I will cause men to walk upon you, even my people Israel; and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them of men.", "web": "Yes, I will cause men to walk on you, even my people Israel; and they shall possess you, and you shall be their inheritance, and you shall no more henceforth bereave them of children.", "bsb": "Yes, I will cause My people Israel to walk upon you; they will possess you, and you will be their inheritance, and you will no longer deprive them of their children.", "asv": "Yea, I will cause men to walk upon you, even my people Israel; and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them of children.", "ylt": "And I have caused man to walk over you, --My people Israel, And they possess thee, and thou hast been to them for an inheritance, And thou dost add no more to bereave them.", "dra": "And I will bring men upon you, my people Israel, and they shall possess thee for their inheritance: and thou shalt be their inheritance, and shalt no more henceforth be without them.", "bbe": "Yes, I will have you walked on by the feet of men, even my people Israel; they will have you for a heritage and you will be theirs, and never again will you take their children from them.", "geneva": "Yea, I wil cause men to walke vpon you, euen my people Israel, and they shall possesse you, and ye shalbe their inheritance, and ye shall no more henceforth depriue them of men.", "wycliffe": "And Y schal brynge men on you, my puple Israel, and bi eritage thei schulen welde thee, and thou schalt be to hem in to eritage; and thou schalt no more leie to, that thou be with out hem.", "rotherham": "And I will bring upon you—men even my people Israel That they may possess thee, So shalt thou be theirs, as an inheritance, -And thou shalt no more again make them childless.", "darby": "And I will cause men to walk upon you, even my people Israel; and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them of children.", "twenty": "", "jps": "Yea, I will cause men to walk upon you, even my people Israel, and they shall possess thee, and thou shalt be their inheritance; and thou shalt no more henceforth bereave them of children.", "acv": "Yea, I will cause men to walk upon you, even my people Israel, and they shall possess thee, and thou shall be their inheritance, and thou shall no more henceforth bereave them of sons.", "anderson": "", "haweis": "", "noyes": "Yea, I will cause men, even my people Israel, to walk upon you, and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them of children.", "webster": "Yes, I will cause men to walk upon you, [even] my people Israel; and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them [of men].", "vulgate": "et adducam super vos homines populum meum Israhel et hereditate possidebunt te et eris eis in hereditatem et non addes ultra ut absque eis sis;", "brenton": "And I will increase men upon you, even my people Israel; and they shall inherit you, and ye shall be to them for a possession; and ye shall no more be bereaved of them."}}, {"v": 13, "ref": "36:13", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה יַ֚עַן אֹמְרִ֣ים לָ/כֶ֔ם אֹכֶ֥לֶת אָדָ֖ם אתי אָ֑תְּ וּ/מְשַׁכֶּ֥לֶת גוי/ך גּוֹיַ֖יִ/ךְ הָיִֽית", "en": {"kjv": "Thus saith the Lord God; Because they say unto you, Thou land devourest up men, and hast bereaved thy nations;", "web": "Thus says the Lord Yahweh: Because they say to you, You are a devourer of men, and have been a bereaver of your nation;", "bsb": "For this is what the Lord GOD says: Because people say to you, ‘You devour men and deprive your nation of its children,’", "asv": "Thus saith the Lord Jehovah: Because they say unto you, Thou land art a devourer of men, and hast been a bereaver of thy nation;", "ylt": "Thus said the Lord Jehovah: Because they are saying to you: A devourer of men art thou, And a bereaver of thy nations thou hast been,", "dra": "Thus saith the Lord God: Because thy say of you: Thou art a devourer of men, and one that suffocatest thy nation:", "bbe": "This is what the Lord has said: Because they say to you, You, O land, are the destruction of men, causing loss of children to your nation;", "geneva": "Thus sayth the Lord God, because they say vnto you, Thou land deuourest vp men, and hast bene a waster of thy people,", "wycliffe": "The Lord God seith these thingis, For that that thei seien of you, Thou art a deuouresse of men, and stranglist thi folk;", "rotherham": "Thus saith My Lord, Yahweh, Because they are saying to you. A devourer of men, thou art, And one that didst make childless thy nations, hast thou been", "darby": "Thus saith the Lord Jehovah: Because they say unto you, Thou devourest men, and hast bereaved thy nation,", "twenty": "", "jps": "Thus saith the L-rd GOD: Because they say unto you: Thou land art a devourer of men, and hast been a bereaver of thy nations;", "acv": "Thus says the lord Jehovah: Because they say to you, Thou O land are a devourer of men, and have been a bereaver of thy nation,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Because they say of you, \"Thou hast devoured men, and made thy people childless!\"", "webster": "Thus saith the Lord GOD; Because they say to you, Thou [land] devourest men, and hast bereaved thy nations;", "vulgate": "haec dicit Dominus Deus pro eo quod dicunt de vobis devoratrix hominum es et suffocans gentem tuam;", "brenton": "Thus saith the Lord God: Because they said to thee, Thou land devourest men, and hast been bereaved of thy nation;"}}, {"v": 14, "ref": "36:14", "o": "לָ/כֵ֗ן אָדָם֙ לֹא תֹ֣אכְלִי ע֔וֹד ו/גוי/ך וְ/גוֹיַ֖יִ/ךְ לֹ֣א תכשלי תְשַׁכְּלִי ע֑וֹד נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Therefore thou shalt devour men no more, neither bereave thy nations any more, saith the Lord God.", "web": "therefore you shall devour men no more, neither bereave your nation any more, says the Lord Yahweh;", "bsb": "therefore you will no longer devour men or deprive your nation of its children, declares the Lord GOD.", "asv": "therefore thou shalt devour men no more, neither bereave thy nation any more, saith the Lord Jehovah;", "ylt": "Therefore, man thou devourest no more, And thy nations thou causest not to stumble any more, An affirmation of the Lord Jehovah.", "dra": "Therefore thou shalt devour men no more nor destroy thy nation any more, saith the Lord God.", "bbe": "For this reason you will no longer take the lives of men and will never again be the cause of loss of children to your nation, says the Lord.", "geneva": "Therefore thou shalt deuoure men no more, neither waste thy people henceforth, sayth the Lord God,", "wycliffe": "therfor thou schalt no more ete men, and thou schalt no more sle thi folk, seith the Lord God.", "rotherham": "Therefore, men, shalt thou not devour any more,- And thy nations, shalt thou make childless no more, Declareth My Lord Yahweh;", "darby": "therefore thou shalt devour men no more, neither bereave thy nation any more, saith the Lord Jehovah;", "twenty": "", "jps": "therefore thou shalt devour men no more, neither bereave thy nations any more, saith the L-rd GOD;", "acv": "therefore thou shall no more devour men, nor bereave thy nation any more, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "therefore thou shalt devour men no more, and no more make thy people childless, saith the Lord Jehovah.", "webster": "Therefore thou shalt devour men no more, neither bereave thy nations any more, saith the Lord GOD.", "vulgate": "propterea homines non comedes amplius et gentem tuam non necabis ultra ait Dominus Deus;", "brenton": "therefore thou shalt no more devour men, and thou shalt no more bereave thy nation, saith the Lord God."}}, {"v": 15, "ref": "36:15", "o": "וְ/לֹא אַשְׁמִ֨יעַ אֵלַ֤יִ/ךְ עוֹד֙ כְּלִמַּ֣ת הַ/גּוֹיִ֔ם וְ/חֶרְפַּ֥ת עַמִּ֖ים לֹ֣א תִשְׂאִי ע֑וֹד ו/גוי/ך וְ/גוֹיַ֨יִ/ךְ֙ לֹא תַכְשִׁ֣לִי ע֔וֹד נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Neither will I cause men to hear in thee the shame of the heathen any more, neither shalt thou bear the reproach of the people any more, neither shalt thou cause thy nations to fall any more, saith the Lord God.", "web": "neither will I let you hear any more the shame of the nations, neither shall you bear the reproach of the peoples any more, neither shall you cause your nation to stumble any more, says the Lord Yahweh.", "bsb": "I will no longer allow the taunts of the nations to be heard against you, and you will no longer endure the reproach of the peoples or cause your nation to stumble, declares the Lord GOD.”", "asv": "neither will I let thee hear any more the shame of the nations, neither shalt thou bear the reproach of the peoples any more, neither shalt thou cause thy nation to stumble any more, saith the Lord Jehovah.", "ylt": "And I proclaim not unto thee any more the shame of the nations, And the reproach of peoples thou bearest no more, And thy nations stumble not any more, An affirmation of the Lord Jehovah.'", "dra": "Neither will I cause men to hear in thee the shame of the nations any more, nor shalt thou bear the reproach of the people, nor lose thy nation any more, saith the Lord God.", "bbe": "And I will not let the shaming of the nations come to your ears, and no longer will you be looked down on by the peoples, says the Lord.", "geneva": "Neither will I cause men to heare in thee the shame of the heathen any more, neither shalt thou beare the reproche of the people any more, neither shalt cause thy folke to fal any more, saith the Lord God.", "wycliffe": "And Y schal no more make herd in thee the schenschipe of hethene men, and thou schalt no more bere the schenschipe of puplis, and thou schalt no more leese thi folk, seith the Lord God.", "rotherham": "And I will not suffer to be heard against thee any more, the insult of the nations, And the reproach of the peoples, shalt thou not bear any more,- And thy nations, shalt thou not cause to stumble any more, Declareth My Lord Yahweh.", "darby": "neither will I cause thee to hear the ignominy of the nations any more, and thou shalt not bear the reproach of the peoples any more, neither shalt thou cause thy nation to fall any more, saith the Lord Jehovah.", "twenty": "", "jps": "neither will I suffer the shame of the nations any more to be heard against thee, neither shalt thou bear the reproach of the peoples any more, neither shalt thou cause thy nations to stumble any more, saith the L-rd GOD.'", "acv": "Neither will I let thee hear any more the shame of the nations, nor shall thou bear the reproach of the peoples any more, nor shall thou cause thy nation to stumble any more, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Neither will I cause the reproach of the nations to be heard against thee any more, neither shalt thou bear the derision of the nations any more, neither shalt thou make thy nation childless any more, saith the lord Jehovah.", "webster": "Neither will I cause [men] to hear in thee the shame of the heathen any more, neither shalt thou bear the reproach of the people any more, neither shalt thou cause thy nations to fall any more, saith the Lord GOD.", "vulgate": "nec auditam faciam in te amplius confusionem gentium et obprobrium populorum nequaquam portabis et gentem tuam non amittes amplius ait Dominus Deus;", "brenton": "And there shall no more be heard against you the reproach of the nations, and ye shall no more bear the revilings of the peoples, saith the Lord God."}}, {"v": 16, "ref": "36:16", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "Moreover the word of the Lord came unto me, saying,", "web": "Moreover Yahweh’s word came to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "Moreover the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "Then the word of the Lord came to me, saying,", "geneva": "Moreouer the word of the Lord came vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me, and he seide, Thou,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "Moreover the word of HaShem came unto me, saying:", "acv": "Moreover the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, the word of Jehovah came to me, saying:", "webster": "Moreover the word of the LORD came to me, saying,", "vulgate": "et factum est verbum Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 17, "ref": "36:17", "o": "בֶּן אָדָ֗ם בֵּ֤ית יִשְׂרָאֵל֙ יֹשְׁבִ֣ים עַל אַדְמָתָ֔/ם וַ/יְטַמְּא֣וּ אוֹתָ֔/הּ בְּ/דַרְכָּ֖/ם וּ/בַ/עֲלִֽילוֹתָ֑/ם כְּ/טֻמְאַת֙ הַ/נִּדָּ֔ה הָיְתָ֥ה דַרְכָּ֖/ם לְ/פָנָֽ/י", "en": {"kjv": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their own way and by their doings: their way was before me as the uncleanness of a removed woman.", "web": "Son of man, when the house of Israel lived in their own land, they defiled it by their way and by their doings: their way before me was as the uncleanness of a woman in her impurity.", "bsb": "“Son of man, when the people of Israel lived in their land, they defiled it by their own ways and deeds. Their behavior before Me was like the uncleanness of a woman’s impurity.", "asv": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their way and by their doings: their way before me was as the uncleanness of a woman in her impurity.", "ylt": "`Son of man, The house of Israel are dwelling on their land, And they defile it by their way and by their doings, As the uncleanness of a separated one hath their way been before Me.", "dra": "Son of man, when the house of Israel dwelt in their own land, they defiled it with their ways, and with their doings: their way was before me like the uncleanness of a menstruous woman.", "bbe": "Son of man, when the children of Israel were living in their land, they made it unclean by their way and their acts: their way before me was as when a woman is unclean at the time when she is kept separate.", "geneva": "Sonne of man, when the house of Israel dwelt in their owne lande, they defiled it by their owne wayes, and by their deedes: their way was before me as the filthinesse of the menstruous.", "wycliffe": "sone of man, the hous of Israel dwelliden in her lond, and thei defouliden it in her weies, and in her studies; bi the vnclennesse of a womman in rotun blood the weie of hem is maad bifor me.", "rotherham": "Son of man The house of Israel were dwelling upon their own soil, But they defiled it by their way, and by their doings. Like the defilement of her that is removed, became their way before me.", "darby": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their way and by their doings: their way was before me as the uncleanness of a woman in her separation.", "twenty": "", "jps": "'Son of man, when the house of Israel dwelt in their own land, they defiled it by their way and by their doings; their way before Me was as the uncleanness of a woman in her impurity.", "acv": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their way and by their doings. Their way before me was as the uncleanness of a woman in her impurity.", "anderson": "", "haweis": "", "noyes": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their way and by their doings; their way before me was as the impurity of an unclean woman.", "webster": "Son of man, when the house of Israel dwelt in their own land, they defiled it by their own way and by their doings: their way was before me as the uncleanness of a removed woman.", "vulgate": "fili hominis domus Israhel habitaverunt in humo sua et polluerunt eam in viis suis et in studiis suis iuxta inmunditiam menstruatae facta est via eorum coram me;", "brenton": "Son of man, the house of Israel dwelt upon their land, and defiled it by their way, and with their idols, and with their uncleannesses; and their way was before me like the uncleanness of a removed woman."}}, {"v": 18, "ref": "36:18", "o": "וָ/אֶשְׁפֹּ֤ךְ חֲמָתִ/י֙ עֲלֵי/הֶ֔ם עַל הַ/דָּ֖ם אֲשֶׁר שָׁפְכ֣וּ עַל הָ/אָ֑רֶץ וּ/בְ/גִלּוּלֵי/הֶ֖ם טִמְּאֽוּ/הָ", "en": {"kjv": "Wherefore I poured my fury upon them for the blood that they had shed upon the land, and for their idols wherewith they had polluted it:", "web": "Therefore I poured out my wrath on them for the blood which they had poured out on the land, and because they had defiled it with their idols;", "bsb": "So I poured out My wrath upon them because of the blood they had shed on the land, and because they had defiled it with their idols.", "asv": "Wherefore I poured out my wrath upon them for the blood which they had poured out upon the land, and because they had defiled it with their idols;", "ylt": "And I do pour out My fury upon them For the blood that they shed on the land, And with their idols they have defiled it.", "dra": "And I poured out my indignation upon them for the blood which they had shed upon the land, and with their idols they defiled it.", "bbe": "So I let loose my wrath on them because of those whom they had violently put to death in the land, and because they had made it unclean with their images:", "geneva": "Wherfore I powred my wrath vpon them, for the blood that they had shed in the land, and for their idoles, wherewith they had polluted it.", "wycliffe": "And Y schedde out myn indignacioun on hem, for blood which thei schedden on the lond, and in her idols thei defouliden it.", "rotherham": "So I poured out mine indignation upon them, Because of the blood which they had shed upon the land,- Yea with their manufactured gods, had they defiled it.", "darby": "And I poured out my fury upon them for the blood that they had shed upon the land, and because they had defiled it with their idols.", "twenty": "", "jps": "Wherefore I poured out My fury upon them for the blood which they had shed upon the land, and because they had defiled it with their idols;", "acv": "Therefore I poured out my wrath upon them for the blood which they had poured out upon the land, and because they had defiled it with their idols.", "anderson": "", "haweis": "", "noyes": "Wherefore I poured my fury upon them for the blood which they had shed in the land, and because they had polluted it with their idols.", "webster": "Wherefore I poured my fury upon them for the blood that they had shed upon the land, and for their idols [with which] they had polluted it:", "vulgate": "et effudi indignationem meam super eos pro sanguine quem fuderunt super terram et in idolis suis polluerunt eam;", "brenton": "So I poured out my wrath upon them:"}}, {"v": 19, "ref": "36:19", "o": "וָ/אָפִ֤יץ אֹתָ/ם֙ בַּ/גּוֹיִ֔ם וַ/יִּזָּר֖וּ בָּ/אֲרָצ֑וֹת כְּ/דַרְכָּ֥/ם וְ/כַ/עֲלִילוֹתָ֖/ם שְׁפַטְתִּֽי/ם", "en": {"kjv": "And I scattered them among the heathen, and they were dispersed through the countries: according to their way and according to their doings I judged them.", "web": "and I scattered them among the nations, and they were dispersed through the countries: according to their way and according to their doings I judged them.", "bsb": "I dispersed them among the nations, and they were scattered throughout the lands. I judged them according to their ways and deeds.", "asv": "and I scattered them among the nations, and they were dispersed through the countries: according to their way and according to their doings I judged them.", "ylt": "And I scatter them among nations, And they are spread through lands, According to their way, and according to their doings, I have judged them.", "dra": "And I scattered them among the nations, and they are dispersed through the countries: I have judged them according to their ways, and their devices.", "bbe": "And I sent them in flight among the nations and wandering through the countries: I was their judge, rewarding them for their way and their acts.", "geneva": "And I scattered them among the heathen, and they were dispersed through the countries for according to their wayes, and according to their deedes, I iudged them.", "wycliffe": "And Y scateride hem among hethene men, and thei weren wyndewid to londis; Y demede hem bi the weies and fyndyngis of hem.", "rotherham": "So I dispersed them among the nations, And they were scattered throughout the lands,— According to their way and according to their doings, I judged them.", "darby": "And I scattered them among the nations, and they were dispersed through the countries: according to their way and according to their doings I judged them.", "twenty": "", "jps": "and I scattered them among the nations, and they were dispersed through the countries; according to their way and according to their doings I judged them.", "acv": "And I scattered them among the nations, and they were dispersed through the countries. I judged them according to their way and according to their doings.", "anderson": "", "haweis": "", "noyes": "And I scattered them among the nations, and they were dispersed through the countries; according to their way and according to their doings I judged them.", "webster": "And I scattered them among the heathen, and they were dispersed through the countries: according to their way and according to their doings I judged them.", "vulgate": "et dispersi eos in gentes et ventilati sunt in terris iuxta vias eorum et adinventiones iudicavi eos;", "brenton": "and I dispersed them among the nations, and utterly scattered them through the countries: I judged them according to their way and according to their sin."}}, {"v": 20, "ref": "36:20", "o": "וַ/יָּב֗וֹא אֶל הַ/גּוֹיִם֙ אֲשֶׁר בָּ֣אוּ שָׁ֔ם וַֽ/יְחַלְּל֖וּ אֶת שֵׁ֣ם קָדְשִׁ֑/י בֶּ/אֱמֹ֤ר לָ/הֶם֙ עַם יְהוָ֣ה אֵ֔לֶּה וּ/מֵ/אַרְצ֖/וֹ יָצָֽאוּ", "en": {"kjv": "And when they entered unto the heathen, whither they went, they profaned my holy name, when they said to them, These are the people of the Lord, and are gone forth out of his land.", "web": "When they came to the nations, where they went, they profaned my holy name; in that men said of them, These are the people of Yahweh, and are gone out of his land.", "bsb": "And wherever they went among the nations, they profaned My holy name, because it was said of them, ‘These are the people of the LORD, yet they had to leave His land.’", "asv": "And when they came unto the nations, whither they went, they profaned my holy name; in that men said of them, These are the people of Jehovah, and are gone forth out of his land.", "ylt": "And one goeth in unto the nations whither they have gone, And they pollute My holy name by saying to them, The people of Jehovah are these, And from His land they have gone forth.", "dra": "And when they entered among the nations whither they went, they profaned my holy name, when it was said of them: This is the people of the Lord, and they are come forth out of his land.", "bbe": "And when they came among the nations, wherever they went, they made my holy name unclean, when it was said of them, These are the people of the Lord who have gone out from his land.", "geneva": "And when they entred vnto the heathen, whither they went, they polluted mine holy Name, when they sayd of them, These are the people of the Lord, and are gone out of his land.", "wycliffe": "And thei entriden to hethene men, to whiche thei entriden, and defouliden myn hooli name, whanne it was seid of hem, This is the puple of the Lord, and thei yeden out of the lond of hym.", "rotherham": "But when they entered among the nations where they did enter, then profaned they my holy Name,—in that it was said of them The people of Yahweh, these! Yet from his land, have they come forth!", "darby": "And when they came to the nations whither they went, they profaned my holy name, when it was said of them, These are the people of Jehovah, and they are gone forth out of his land.", "twenty": "", "jps": "And when they came unto the nations, whither they came, they profaned My holy name; in that men said of them: These are the people of HaShem, and are gone forth out of His land.", "acv": "And when they came to the nations where they went, they profaned my holy name, in that men said of them, These are the people of Jehovah, and have gone forth out of his land.", "anderson": "", "haweis": "", "noyes": "And when they came to the nations whither they went, they polluted my holy name, in that it was said of them, \"These are the people of Jehovah, and they are gone forth out of his land.\"", "webster": "And when they entered among the heathen, whither they went, they profaned my holy name, when they said to them, These [are] the people of the LORD, and are gone forth out of his land.", "vulgate": "et ingressi sunt ad gentes ad quas introierunt et polluerunt nomen sanctum meum cum diceretur de eis populus Domini iste est et de terra eius egressi sunt;", "brenton": "And they went in among the nations, among which they went, and they profaned my holy name, while it was said of them, These are the people of the Lord, and they came forth out of his land."}}, {"v": 21, "ref": "36:21", "o": "וָ/אֶחְמֹ֖ל עַל שֵׁ֣ם קָדְשִׁ֑/י אֲשֶׁ֤ר חִלְּל֨וּ/הוּ֙ בֵּ֣ית יִשְׂרָאֵ֔ל בַּ/גּוֹיִ֖ם אֲשֶׁר בָּ֥אוּ שָֽׁמָּ/ה", "en": {"kjv": "But I had pity for mine holy name, which the house of Israel had profaned among the heathen, whither they went.", "web": "But I had respect for my holy name, which the house of Israel had profaned among the nations, where they went.", "bsb": "But I had concern for My holy name, which the house of Israel had profaned among the nations to which they had gone.", "asv": "But I had regard for my holy name, which the house of Israel had profaned among the nations, whither they went.", "ylt": "And I have pity on My holy name, That the house of Israel have polluted among nations whither they have gone in.", "dra": "And I have regarded my own holy name, which the house of Israel hath profaned among the nations to which they went in.", "bbe": "But I had pity for my holy name which the children of Israel had made unclean wherever they went.", "geneva": "But I fauoured mine holy Name which the house of Israel had polluted among the heathen, whither they went.", "wycliffe": "And Y sparide myn hooli name, which the hous of Israel hadde defoulid among hethene men, to whiche thei entriden.", "rotherham": "So then I had tender regard for my holy Name,- Which the house of Israel had profaned, among the nations, where they had entered.", "darby": "But I had pity for my holy name, which the house of Israel had profaned among the nations whither they went.", "twenty": "", "jps": "But I had pity for My holy name, which the house of Israel had profaned among the nations, whither they came.", "acv": "But I had regard for my holy name, which the house of Israel had profaned among the nations where they went.", "anderson": "", "haweis": "", "noyes": "Therefore I will have regard to my holy name, which the house of Israel have polluted among the nations whither they are gone.", "webster": "But I had pity for my holy name, which the house of Israel had profaned among the heathen, whither they went.", "vulgate": "et peperci nomini meo sancto quod polluerat domus Israhel in gentibus ad quas ingressi sunt;", "brenton": "But I spared them for the sake of my holy name, which the house of Israel profaned among the nations, among whom they went."}}, {"v": 22, "ref": "36:22", "o": "לָ/כֵ֞ן אֱמֹ֣ר לְ/בֵֽית יִשְׂרָאֵ֗ל כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה לֹ֧א לְמַעַנְ/כֶ֛ם אֲנִ֥י עֹשֶׂ֖ה בֵּ֣ית יִשְׂרָאֵ֑ל כִּ֤י אִם לְ/שֵׁם קָדְשִׁ/י֙ אֲשֶׁ֣ר חִלַּלְתֶּ֔ם בַּ/גּוֹיִ֖ם אֲשֶׁר בָּ֥אתֶם שָֽׁם", "en": {"kjv": "Therefore say unto the house of Israel, Thus saith the Lord God; I do not this for your sakes, O house of Israel, but for mine holy name’s sake, which ye have profaned among the heathen, whither ye went.", "web": "Therefore tell the house of Israel, Thus says the Lord Yahweh: I don’t do this for your sake, house of Israel, but for my holy name, which you have profaned among the nations, where you went.", "bsb": "Therefore tell the house of Israel that this is what the Lord GOD says: It is not for your sake that I will act, O house of Israel, but for My holy name, which you profaned among the nations to which you went.", "asv": "Therefore say unto the house of Israel, Thus saith the Lord Jehovah: I do not this for your sake, O house of Israel, but for my holy name, which ye have profaned among the nations, whither ye went.", "ylt": "Therefore, say to the house of Israel, Thus said the Lord Jehovah: Not for your sake am I working, O house of Israel, But--for My holy name, That ye have polluted among nations whither ye have gone in.", "dra": "Therefore thou shalt say to the house of Israel: Thus saith the Lord God: It is not for your sake that I will do this, O house of Israel, but for my holy name's sake, which you have profaned among the nations whither you went.", "bbe": "For this cause say to the children of Israel, This is what the Lord has said: I am doing this, not because of you, O children of Israel, but because of my holy name, which you have made unclean among the nations wherever you went.", "geneva": "Therfore say vnto the house of Israel, Thus saith ye Lord God, I doe not this for your sakes, O house of Israel, but for mine holy Names sake, which yee polluted among the heathen whither ye went.", "wycliffe": "Therfor thou schalt seie to the hous of Israel, The Lord God seith these thingis, O! ye hous of Israel, not for you Y schal do, but for myn hooli name, which ye defouliden among hethene men, to whiche ye entriden.", "rotherham": "Therefore say thou to the house of Israel Thus saith My Lord Yahweh, Not for your sakes, am I working. O house of Israel, But for my holy Name which ye have profaned, among the nations where ye have entered;", "darby": "Therefore say unto the house of Israel, Thus saith the Lord Jehovah: I do not this for your sakes, O house of Israel, but for my holy name, which ye have profaned among the nations whither ye went.", "twenty": "", "jps": "Therefore say unto the house of Israel: Thus saith the L-rd GOD: I do not this for your sake, O house of Israel, but for My holy name, which ye have profaned among the nations, whither ye came.", "acv": "Therefore say to the house of Israel, Thus says the lord Jehovah: I do this not for your sake, O house of Israel, but for my holy name, which ye have profaned among the nations where ye went.", "anderson": "", "haweis": "", "noyes": "Therefore say to the house of Israel, Thus saith the Lord Jehovah: Not for your own sakes do I this, O house of Israel, but for my holy name, which ye have polluted among the nations whither ye are gone.", "webster": "Therefore say to the house of Israel, Thus saith the Lord GOD; I do not [this] for your sakes, O house of Israel, but for my holy name's sake, which ye have profaned among the heathen, whither ye went.", "vulgate": "idcirco dices domui Israhel haec dicit Dominus Deus non propter vos ego faciam domus Israhel sed propter nomen sanctum meum quod polluistis in gentibus ad quas intrastis;", "brenton": "Therefore say to the house of Israel, Thus saith the Lord; I do not this, O house of Israel, for your sakes, but because of my holy name, which ye have profaned among the nations, among whom ye went."}}, {"v": 23, "ref": "36:23", "o": "וְ/קִדַּשְׁתִּ֞י אֶת שְׁמִ֣/י הַ/גָּד֗וֹל הַֽ/מְחֻלָּל֙ בַּ/גּוֹיִ֔ם אֲשֶׁ֥ר חִלַּלְתֶּ֖ם בְּ/תוֹכָ֑/ם וְ/יָדְע֨וּ הַ/גּוֹיִ֜ם כִּי אֲנִ֣י יְהוָ֗ה נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה בְּ/הִקָּדְשִׁ֥/י בָ/כֶ֖ם לְ/עֵינֵי/הֶֽם", "en": {"kjv": "And I will sanctify my great name, which was profaned among the heathen, which ye have profaned in the midst of them; and the heathen shall know that I am the Lord, saith the Lord God, when I shall be sanctified in you before their eyes.", "web": "I will sanctify my great name, which has been profaned among the nations, which you have profaned in their midst; and the nations shall know that I am Yahweh, says the Lord Yahweh, when I shall be sanctified in you before their eyes.", "bsb": "I will show the holiness of My great name, which has been profaned among the nations—the name you have profaned among them. Then the nations will know that I am the LORD, declares the Lord GOD, when I show My holiness in you before their eyes.", "asv": "And I will sanctify my great name, which hath been profaned among the nations, which ye have profaned in the midst of them; and the nations shall know that I am Jehovah, saith the Lord Jehovah, when I shall be sanctified in you before their eyes.", "ylt": "And I have sanctified My great name, That is profaned among nations, That ye have polluted in your midst, And known have the nations that I am Jehovah, An affirmation of the Lord Jehovah, In My being sanctified in you before your eyes.", "dra": "And I will sanctify my great name, which was profaned among the Gentiles, which you have profaned in the midst of them: that the Gentiles may know that I am the Lord, saith the Lord of hosts, when I shall be sanctified in you before their eyes.", "bbe": "And I will make holy my great name which has been made unclean among the nations, which you have made unclean among them; and it will be clear to the nations that I am the Lord, says the Lord, when I make myself holy in you before their eyes.", "geneva": "And I wil sanctifie my great Name, which was polluted among the heathen, among whome you haue polluted it, and the heathen shall know that I am the Lord, sayth the Lord God, when I shalbe sanctified in you before their eyes.", "wycliffe": "And Y schal halewe my greet name, which is defoulid among hethene men, whiche ye defouliden in the myddis of hem; that hethene men wite, that Y am the Lord, seith the Lord of oostis, whanne Y schal be halewid in you before hem.", "rotherham": "Therefore will I hallow my great Name, that hath been profaned among the nations, which ye have profaned in their midst,-So shall the nations know that I am Yahweh Declareth My Lord, Yahweh, When I have hallowed myself in you, before their eyes.", "darby": "And I will hallow my great name, which was profaned among the nations, which ye have profaned in the midst of them; and the nations shall know that I [am] Jehovah, saith the Lord Jehovah, when I shall be hallowed in you before their eyes.", "twenty": "", "jps": "And I will sanctify My great name, which hath been profaned among the nations, which ye have profaned in the midst of them; and the nations shall know that I am HaShem, saith the L-rd GOD, when I shall be sanctified in you before their eyes.", "acv": "And I will sanctify my great name, which has been profaned among the nations, which ye have profaned in the midst of them. And the nations shall know that I am Jehovah, says the lord Jehovah, when I shall be sanctified in you before their eyes.", "anderson": "", "haweis": "", "noyes": "And I will sanctify my great name, which hath been polluted among the nations, which ye have profaned in the midst of them; and the nations shall know that I am Jehovah, when I shall be sanctified in regard to you, before their eyes, saith the Lord Jehovah.", "webster": "And I will sanctify my great name, which was profaned among the heathen, which ye have profaned in the midst of them; and the heathen shall know that I [am] the LORD, saith the Lord GOD, when I shall be sanctified in you before their eyes.", "vulgate": "et sanctificabo nomen meum magnum quod pollutum est inter gentes quod polluistis in medio earum ut sciant gentes quia ego Dominus ait Dominus exercituum cum sanctificatus fuero in vobis coram eis;", "brenton": "And I will sanctify my great name, which was profaned among the nations, which ye profaned in the midst of them; and the nations shall know that I am the Lord, when I am sanctified among you before their eyes."}}, {"v": 24, "ref": "36:24", "o": "וְ/לָקַחְתִּ֤י אֶתְ/כֶם֙ מִן הַ/גּוֹיִ֔ם וְ/קִבַּצְתִּ֥י אֶתְ/כֶ֖ם מִ/כָּל הָ/אֲרָצ֑וֹת וְ/הֵבֵאתִ֥י אֶתְ/כֶ֖ם אֶל אַדְמַתְ/כֶֽם", "en": {"kjv": "For I will take you from among the heathen, and gather you out of all countries, and will bring you into your own land.", "web": "For I will take you from among the nations, and gather you out of all the countries, and will bring you into your own land.", "bsb": "For I will take you from among the nations and gather you out of all the countries, and I will bring you back into your own land.", "asv": "For I will take you from among the nations, and gather you out of all the countries, and will bring you into your own land.", "ylt": "And I have taken you out of the nations, And have gathered you out of all the lands, And I have brought you in unto your land,", "dra": "For I will take you from among the Gentiles, and will gather you together out of all the countries, and will bring you into your own land.", "bbe": "For I will take you out from among the nations, and get you together from all the countries, and take you into your land.", "geneva": "For I will take you from among the heathen, and gather you out of all countries, and will bring you into your owne land.", "wycliffe": "For Y schal take awei you fro hethene men, and Y schal gadere you fro alle londis, and Y schal brynge you in to youre lond.", "rotherham": "Therefore will I take you from among the nations, And gather you out of all the lands,- And will bring you upon your own soil;", "darby": "And I will take you from among the nations, and gather you out of all the countries, and will bring you into your own land.", "twenty": "", "jps": "For I will take you from among the nations, and gather you out of all the countries, and will bring you into your own land.", "acv": "For I will take you from among the nations, and gather you out of all the countries, and will bring you into your own land.", "anderson": "", "haweis": "", "noyes": "For I will take you from among the nations, and gather you out of all countries, and bring you into your own land.", "webster": "For I will take you from among the heathen, and gather you out of all countries, and will bring you into your own land.", "vulgate": "tollam quippe vos de gentibus et congregabo de universis terris et adducam vos in terram vestram;", "brenton": "And I will take you out from the nations, and will gather you out of all the lands, and will bring you into your own land:"}}, {"v": 25, "ref": "36:25", "o": "וְ/זָרַקְתִּ֧י עֲלֵי/כֶ֛ם מַ֥יִם טְהוֹרִ֖ים וּ/טְהַרְתֶּ֑ם מִ/כֹּ֧ל טֻמְאוֹתֵי/כֶ֛ם וּ/מִ/כָּל גִּלּ֥וּלֵי/כֶ֖ם אֲטַהֵ֥ר אֶתְ/כֶֽם", "en": {"kjv": "Then will I sprinkle clean water upon you, and ye shall be clean: from all your filthiness, and from all your idols, will I cleanse you.", "web": "I will sprinkle clean water on you, and you shall be clean: from all your filthiness, and from all your idols, will I cleanse you.", "bsb": "I will also sprinkle clean water on you, and you will be clean. I will cleanse you from all your impurities and all your idols.", "asv": "And I will sprinkle clean water upon you, and ye shall be clean: from all your filthiness, and from all your idols, will I cleanse you.", "ylt": "And I have sprinkled over you clean water, And ye have been clean; From all your uncleannesses, and from all your idols, I do cleanse you.", "dra": "And I will pour upon you clean water, and you shall be cleansed from all your filthiness, and I will cleanse you from all your idols.", "bbe": "And I will put clean water on you so that you may be clean: from all your unclean ways and from all your images I will make you clean.", "geneva": "Then wil I powre cleane water vpon you, and ye shalbe cleane: yea, from all your filthines, and from all your idoles wil I clense you.", "wycliffe": "And Y schal schede out clene watir on you, and ye schulen be clensid fro alle youre filthis; and Y schal clense you fro alle youre idols.", "rotherham": "And I will throw upon you clean water and ye shall be clean,— From all your uncleannesses and from all your manufactured gods, will I cleanse you;", "darby": "And I will sprinkle clean water upon you, and ye shall be clean: from all your uncleannesses and from all your idols will I cleanse you.", "twenty": "", "jps": "And I will sprinkle clean water upon you, and ye shall be clean; from all your uncleannesses, and from all your idols, will I cleanse you.", "acv": "And I will sprinkle clean water upon you, and ye shall be clean. I will cleanse you from all your filthiness, and from all your idols.", "anderson": "", "haweis": "", "noyes": "Then will I sprinkle clean water upon you, and ye shall be clean. From all your uncleanness and from all your idols will I cleanse you.", "webster": "Then will I sprinkle clean water upon you, and ye shall be clean: from all your filthiness, and from all your idols, will I cleanse you.", "vulgate": "et effundam super vos aquam mundam et mundabimini ab omnibus inquinamentis vestris et ab universis idolis vestris mundabo vos;", "brenton": "and I will sprinkle clean water upon you, and ye shall be purged from all your uncleannesses, and from all your idols, and I will cleanse you."}}, {"v": 26, "ref": "36:26", "o": "וְ/נָתַתִּ֤י לָ/כֶם֙ לֵ֣ב חָדָ֔שׁ וְ/ר֥וּחַ חֲדָשָׁ֖ה אֶתֵּ֣ן בְּ/קִרְבְּ/כֶ֑ם וַ/הֲסִ֨רֹתִ֜י אֶת לֵ֤ב הָ/אֶ֨בֶן֙ מִ/בְּשַׂרְ/כֶ֔ם וְ/נָתַתִּ֥י לָ/כֶ֖ם לֵ֥ב בָּשָֽׂר", "en": {"kjv": "A new heart also will I give you, and a new spirit will I put within you: and I will take away the stony heart out of your flesh, and I will give you an heart of flesh.", "web": "I will also give you a new heart, and I will put a new spirit within you; and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "bsb": "I will give you a new heart and put a new spirit within you; I will remove your heart of stone and give you a heart of flesh.", "asv": "A new heart also will I give you, and a new spirit will I put within you; and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "ylt": "And I have given to you a new heart, And a new spirit I give in your midst, And I have turned aside the heart of stone out of your flesh, And I have given to you a heart of flesh.", "dra": "And I will give you a new heart, and put a new spirit within you: and I will take away the stony heart out of your flesh, and will give you a heart of flesh.", "bbe": "And I will give you a new heart and put a new spirit in you: I will take away the heart of stone from your flesh, and give you a heart of flesh.", "geneva": "A newe heart also will I giue you, and a new spirit wil I put within you, and I will take away the stonie heart out of your body, and I will giue you an heart of flesh.", "wycliffe": "And Y schal yyue to you a newe herte, and Y schal sette a newe spirit in the myddis of you; and Y schal do awei an herte of stoon fro youre fleisch, and Y schal yyue to you an herte of fleisch,", "rotherham": "And I will give you a new heart, And a new spirit, will I put within you,-And I will take away the heart of stone out of your flesh, And will give you a heart of flesh;", "darby": "And I will give you a new heart, and I will put a new spirit within you; and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "twenty": "", "jps": "A new heart also will I give you, and a new spirit will I put within you; and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "acv": "I will also give you a new heart, and I will put a new spirit within you. And I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "anderson": "", "haweis": "", "noyes": "A new heart also will I give you, and a new spirit will I put within you; and I will take out of your body the heart of stone, and I will give you a heart of flesh.", "webster": "A new heart also will I give you, and a new spirit will I put within you: and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "vulgate": "et dabo vobis cor novum et spiritum novum ponam in medio vestri et auferam cor lapideum de carne vestra et dabo vobis cor carneum;", "brenton": "And I will give you a new heart, and will put a new spirit in you: and I will take away the heart of stone out of your flesh, and will give you a heart of flesh."}}, {"v": 27, "ref": "36:27", "o": "וְ/אֶת רוּחִ֖/י אֶתֵּ֣ן בְּ/קִרְבְּ/כֶ֑ם וְ/עָשִׂ֗יתִי אֵ֤ת אֲשֶׁר בְּ/חֻקַּ/י֙ תֵּלֵ֔כוּ וּ/מִשְׁפָּטַ֥/י תִּשְׁמְר֖וּ וַ/עֲשִׂיתֶֽם", "en": {"kjv": "And I will put my spirit within you, and cause you to walk in my statutes, and ye shall keep my judgments, and do them.", "web": "I will put my Spirit within you, and cause you to walk in my statutes, and you shall keep my ordinances, and do them.", "bsb": "And I will put My Spirit within you and cause you to walk in My statutes and to carefully observe My ordinances.", "asv": "And I will put my Spirit within you, and cause you to walk in my statutes, and ye shall keep mine ordinances, and do them.", "ylt": "And My Spirit I give in your midst, And I have done this, so that in My statutes ye walk, And My judgments ye keep, and have done them.", "dra": "And I will put my spirit in the midst of you: and I will cause you to walk in my commandments, and to keep my judgments, and do them.", "bbe": "And I will put my spirit in you, causing you to be guided by my rules, and you will keep my orders and do them.", "geneva": "And I will put my spirite within you, and cause you to walke in my statutes, and ye shall keepe my iudgements and do them.", "wycliffe": "and Y schal sette my spirit in the myddis of you. And Y schal make that ye go in my comaundementis, and kepe and worche my domes.", "rotherham": "And my spirit, will I put within you, And will cause That in my statutes, ye shall walk, And my regulations, ye shall observe, and do;", "darby": "And I will put my Spirit within you, and cause you to walk in my statutes and keep mine ordinances, and ye shall do them.", "twenty": "", "jps": "And I will put My spirit within you, and cause you to walk in My statutes, and ye shall keep Mine ordinances, and do them.", "acv": "And I will put my Spirit within you, and cause you to walk in my statutes, and ye shall keep my ordinances, and do them.", "anderson": "", "haweis": "", "noyes": "And I will put my spirit within you, and cause you to walk in my statutes, and ye shall keep my commandments and do them.", "webster": "And I will put my spirit within you, and cause you to walk in my statutes, and ye shall keep my judgments, and do [them].", "vulgate": "et spiritum meum ponam in medio vestri et faciam ut in praeceptis meis ambuletis et iudicia mea custodiatis et operemini;", "brenton": "And I will put my Spirit in you, and will cause you to walk in mine ordinances, and to keep my judgments, and do them."}}, {"v": 28, "ref": "36:28", "o": "וִ/ישַׁבְתֶּ֣ם בָּ/אָ֔רֶץ אֲשֶׁ֥ר נָתַ֖תִּי לַ/אֲבֹֽתֵי/כֶ֑ם וִ/הְיִ֤יתֶם לִ/י֙ לְ/עָ֔ם וְ/אָ֣נֹכִ֔י אֶהְיֶ֥ה לָ/כֶ֖ם לֵ/אלֹהִֽים", "en": {"kjv": "And ye shall dwell in the land that I gave to your fathers; and ye shall be my people, and I will be your God.", "web": "You shall dwell in the land that I gave to your fathers; and you shall be my people, and I will be your God.", "bsb": "Then you will live in the land that I gave your forefathers; you will be My people, and I will be your God.", "asv": "And ye shall dwell in the land that I gave to your fathers; and ye shall be my people, and I will be your God.", "ylt": "And ye have dwelt in the land that I have given to your fathers, And ye have been to Me for a people, And I--I am to you for God.", "dra": "And you shall dwell in the land which I gave to your fathers, and you shall be my people, and I will be your God.", "bbe": "So that you may go on living in the land which I gave to your fathers; and you will be to me a people, and I will be to you a God.", "geneva": "And ye shall dwell in the land, that I gaue to your fathers, and ye shalbe my people, and I will be your God.", "wycliffe": "And ye schulen dwelle in the lond, whiche Y yaf to youre fadris; and ye schulen be in to a puple to me, and Y schal be in to a God to you.", "rotherham": "And ye shall dwell in the land which I gave to your fathers,- And ye shall become my people, And I will become your God;", "darby": "And ye shall dwell in the land that I gave to your fathers, and ye shall be my people, and I will be yourGod.", "twenty": "", "jps": "And ye shall dwell in the land that I gave to your fathers; and ye shall be My people, and I will be your G-d.", "acv": "And ye shall dwell in the land that I gave to your fathers, and ye shall be my people, and I will be your God.", "anderson": "", "haweis": "", "noyes": "And ye shall dwell in the land which I gave to your fathers, and ye shall be my people, and I will be your God.", "webster": "And ye shall dwell in the land that I gave to your fathers; and ye shall be my people, and I will be your God.", "vulgate": "et habitabitis in terra quam dedi patribus vestris et eritis mihi in populum et ego ero vobis in Deum;", "brenton": "And ye shall dwell upon the land which I gave to your fathers; and ye shall be to me a people, and I will be to you a God."}}, {"v": 29, "ref": "36:29", "o": "וְ/הוֹשַׁעְתִּ֣י אֶתְ/כֶ֔ם מִ/כֹּ֖ל טֻמְאֽוֹתֵי/כֶ֑ם וְ/קָרָ֤אתִי אֶל הַ/דָּגָן֙ וְ/הִרְבֵּיתִ֣י אֹת֔/וֹ וְ/לֹא אֶתֵּ֥ן עֲלֵי/כֶ֖ם רָעָֽב", "en": {"kjv": "I will also save you from all your uncleannesses: and I will call for the corn, and will increase it, and lay no famine upon you.", "web": "I will save you from all your uncleanness: and I will call for the grain, and will multiply it, and lay no famine on you.", "bsb": "I will save you from all your uncleanness. I will summon the grain and make it plentiful, and I will not bring famine upon you.", "asv": "And I will save you from all your uncleannesses: and I will call for the grain, and will multiply it, and lay no famine upon you.", "ylt": "And I have saved you from all your uncleannesses, And I have called unto the corn, and multiplied it, And I have put no famine upon you.", "dra": "And I will save you from all your uncleannesses: and I will call for corn, and will multiply it, and will lay no famine upon you.", "bbe": "And I will make you free from all your unclean ways: and at my voice the grain will come up and be increased, and I will not let you be short of food.", "geneva": "I will also deliuer you from all your filthinesse, and I will call for corne, and will increase it, and lay no famine vpon you.", "wycliffe": "And Y schal saue you fro alle youre filthis; and Y schal clepe wheete, and Y schal multiplie it, and Y schal not put hungur on you.", "rotherham": "And I will save you out of all your uncleannesses, —And will call for the corn and will increase it, And will not lay upon you famine; And I will save you out of all your uncleannesses, —And will call for the corn and will increase it, And will not lay upon you famine;", "darby": "And I will save you from all your uncleannesses; and I will call for the corn and will multiply it, and lay no famine upon you.", "twenty": "", "jps": "And I will save you from all your uncleannesses; and I will call for the corn, and will increase it, and lay no famine upon you.", "acv": "And I will save you from all your uncleannesses. And I will call for the grain, and will multiply it, and lay no famine upon you.", "anderson": "", "haweis": "", "noyes": "And I will save you from all your uncleanness. And I will call for the corn, and will increase it, and bring no famine upon you.", "webster": "I will also save you from all your uncleannesses: and I will call for the corn, and will increase it, and lay no famine upon you.", "vulgate": "et salvabo vos ex universis inquinamentis vestris et vocabo frumentum et multiplicabo illud et non inponam in vobis famem;", "brenton": "And I will save you from all your uncleannesses: and I will call for the corn, and multiply it, and will not bring famine upon you."}}, {"v": 30, "ref": "36:30", "o": "וְ/הִרְבֵּיתִי֙ אֶת פְּרִ֣י הָ/עֵ֔ץ וּ/תְנוּבַ֖ת הַ/שָּׂדֶ֑ה לְמַ֗עַן אֲ֠שֶׁר לֹ֣א תִקְח֥וּ ע֛וֹד חֶרְפַּ֥ת רָעָ֖ב בַּ/גּוֹיִֽם", "en": {"kjv": "And I will multiply the fruit of the tree, and the increase of the field, that ye shall receive no more reproach of famine among the heathen.", "web": "I will multiply the fruit of the tree, and the increase of the field, that you may receive no more the reproach of famine among the nations.", "bsb": "I will also make the fruit of the trees and the crops of the field plentiful, so that you will no longer bear reproach among the nations on account of famine.", "asv": "And I will multiply the fruit of the tree, and the increase of the field, that ye may receive no more the reproach of famine among the nations.", "ylt": "And I have multiplied the fruit of the tree, And the increase of the field, So that ye receive not any more a reproach of famine among nations.", "dra": "And I will multiply the fruit of the tree, and the increase of the field, that you bear no more the reproach of famine among the nations.", "bbe": "And I will make the tree give more fruit and the field fuller produce, and no longer will you be shamed among the nations for need of food.", "geneva": "For I will multiplie the fruite of the trees, and the increase of the fielde, that ye shall beare no more the reproch of famine among the heathen.", "wycliffe": "And Y schal multiplie the fruyt of tree, and the seedis of the feeld, that ye bere no more the schenschipe of hungur among hethene men.", "rotherham": "And I will multiply The fruit of the tree, and The increase of the field,— To the end that ye may not receive any more the reproach of famine among the nations.", "darby": "And I will multiply the fruit of the trees and the increase of the field, so that ye may receive no more the reproach of famine among the nations.", "twenty": "", "jps": "And I will multiply the fruit of the tree, and the increase of the field, that ye may receive no more the reproach of famine among the nations.", "acv": "And I will multiply the fruit of the tree, and the increase of the field, that ye may no more receive the reproach of famine among the nations.", "anderson": "", "haweis": "", "noyes": "And I will multiply the fruit of the tree, and the increase of the field, that ye may receive no more the reproach of famine among the nations.", "webster": "And I will multiply the fruit of the tree, and the increase of the field, that ye shall receive no more reproach of famine among the heathen.", "vulgate": "et multiplicabo fructum ligni et genimina agri ut non portetis ultra obprobrium famis in gentibus;", "brenton": "And I will multiply the fruit of the trees, and the produce of the field, that ye may not bear the reproach of famine among the nations."}}, {"v": 31, "ref": "36:31", "o": "וּ/זְכַרְתֶּם֙ אֶת דַּרְכֵי/כֶ֣ם הָ/רָעִ֔ים וּ/מַעַלְלֵי/כֶ֖ם אֲשֶׁ֣ר לֹֽא טוֹבִ֑ים וּ/נְקֹֽטֹתֶם֙ בִּ/פְנֵי/כֶ֔ם עַ֚ל עֲוֺנֹ֣תֵי/כֶ֔ם וְ/עַ֖ל תּוֹעֲבֽוֹתֵי/כֶֽם", "en": {"kjv": "Then shall ye remember your own evil ways, and your doings that were not good, and shall lothe yourselves in your own sight for your iniquities and for your abominations.", "web": "Then you shall remember your evil ways, and your doings that were not good; and you shall loathe yourselves in your own sight for your iniquities and for your abominations.", "bsb": "Then you will remember your evil ways and wicked deeds, and you will loathe yourselves for your iniquities and abominations.", "asv": "Then shall ye remember your evil ways, and your doings that were not good; and ye shall loathe yourselves in your own sight for your iniquities and for your abominations.", "ylt": "And ye have remembered your ways that are evil, And your doings that are not good, And have been loathsome in your own faces, For your iniquities, and for your abominations.", "dra": "And you shall remember your wicked ways, and your doings that were not good: and your iniquities, and your wicked deeds shall displease you.", "bbe": "And at the memory of your evil ways and your wrongdoings, you will have bitter hate for yourselves because of your evil-doings and your disgusting ways, O children of Israel.", "geneva": "Then shall ye remember your owne wicked wayes, and your deedes that were not good, and shall iudge your selues worthie to haue bene destroyed for your iniquities, and for your abominations.", "wycliffe": "And ye schulen haue mynde on youre worste weies, and on studies not goode; and youre wickidnessis, and youre grete trespassis schulen displese you.", "rotherham": "Then shall ye call to mind Your ways that were wicked, and Your doings that were not good,- And shall become loathsome in your own sight. For your iniquities and For your abominations.", "darby": "And ye shall remember your evil ways, and your doings which were not good, and shall loathe yourselves for your iniquities and for your abominations.", "twenty": "", "jps": "Then shall ye remember your evil ways, and your doings that were not good; and ye shall loathe yourselves in your own sight for your iniquities and for your abominations.", "acv": "Then ye shall remember your evil ways, and your doings that were not good. And ye shall loathe yourselves in your own sight for your iniquities and for your abominations.", "anderson": "", "haweis": "", "noyes": "Then shall ye remember your evil ways, and your doings which were not good, and ye shall loathe yourselves for your iniquities, and for your abominations.", "webster": "Then shall ye remember your own evil ways, and your doings that [were] not good, and shall lothe yourselves in your own sight for your iniquities, and for your abominations.", "vulgate": "et recordabimini viarum vestrarum pessimarum studiorumque non bonorum et displicebunt vobis iniquitates vestrae et scelera vestra;", "brenton": "And ye shall remember your evil ways and your practices that were not good, and ye shall be hateful in your own sight for your transgressions and for your abominations."}}, {"v": 32, "ref": "36:32", "o": "לֹ֧א לְמַעַנְ/כֶ֣ם אֲנִֽי עֹשֶׂ֗ה נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה יִוָּדַ֖ע לָ/כֶ֑ם בּ֧וֹשׁוּ וְ/הִכָּלְמ֛וּ מִ/דַּרְכֵי/כֶ֖ם בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "Not for your sakes do I this, saith the Lord God, be it known unto you: be ashamed and confounded for your own ways, O house of Israel.", "web": "Nor for your sake do I this, says the Lord Yahweh, be it known to you: be ashamed and confounded for your ways, house of Israel.", "bsb": "It is not for your sake that I will act, declares the Lord GOD—let it be known to you. Be ashamed and disgraced for your ways, O house of Israel!", "asv": "Nor for your sake do Ithis, saith the Lord Jehovah, be it known unto you: be ashamed and confounded for your ways, O house of Israel.", "ylt": "Not for your sake am I working, An affirmation of the Lord Jehovah, Be it known to you, Be ashamed and confounded, because of your ways, O house of Israel.", "dra": "It is not for your sakes that I will do this, saith the Lord God, be it known to you: be confounded, and ashamed at your own ways, O house of Israel.", "bbe": "Not because of you am I doing it, says the Lord; let it be clear to you, and be shamed and made low because of your ways, O children of Israel.", "geneva": "Be it knowen vnto you that I do not this for your sakes, sayth the Lord God: therefore, O ye house of Israel, be ashamed, and confounded for your owne wayes.", "wycliffe": "Not for you Y schal do, seith the Lord God, be it knowun to you; O! the hous of Israel, be ye schent, and be ye aschamed on youre weies.", "rotherham": "Not for your sakes, am I working, Declareth My Lord Yahweh be it known to you,— Turn ye pale and then blush for your ways. O house of Israel.", "darby": "Not for your sakes do I this, saith the Lord Jehovah, be it known unto you: be ashamed and confounded for your ways, O house of Israel.", "twenty": "", "jps": "Not for your sake do I this, saith the L-rd GOD, be it known unto you; be ashamed and confounded for your ways, O house of Israel.", "acv": "I do this not for your sake, says the lord Jehovah; be it known to you. Be ashamed and confounded for your ways, O house of Israel.", "anderson": "", "haweis": "", "noyes": "Not for your own sakes do I this, saith the Lord Jehovah, be it known to you. Be ye ashamed and confounded for your ways, O house of Israel!", "webster": "Not for your sakes do I [this], saith the Lord GOD, be it known to you: be ashamed and confounded for your own ways, O house of Israel.", "vulgate": "non propter vos ego faciam ait Dominus Deus notum sit vobis confundimini et erubescite super viis vestris domus Israhel;", "brenton": "Not for your sakes do I this, saith the Lord God, as it is known to you: be ye ashamed and confounded for your ways, O house of Israel."}}, {"v": 33, "ref": "36:33", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה בְּ/יוֹם֙ טַהֲרִ֣/י אֶתְ/כֶ֔ם מִ/כֹּ֖ל עֲוֺנֽוֹתֵי/כֶ֑ם וְ/הֽוֹשַׁבְתִּי֙ אֶת הֶ֣/עָרִ֔ים וְ/נִבְנ֖וּ הֶ/חֳרָבֽוֹת", "en": {"kjv": "Thus saith the Lord God; In the day that I shall have cleansed you from all your iniquities I will also cause you to dwell in the cities, and the wastes shall be builded.", "web": "Thus says the Lord Yahweh: In the day that I cleanse you from all your iniquities, I will cause the cities to be inhabited, and the waste places shall be built.", "bsb": "This is what the Lord GOD says: On the day I cleanse you from all your iniquities, I will cause the cities to be resettled and the ruins to be rebuilt.", "asv": "Thus saith the Lord Jehovah: In the day that I cleanse you from all your iniquities, I will cause the cities to be inhabited, and the waste places shall be builded.", "ylt": "Thus said the Lord Jehovah: In the day of My cleansing you from all your iniquities, I have caused the cities to be inhabited, And the wastes have been built,", "dra": "Thus saith the Lord God: In the day that I shall cleanse you from all your iniquities, and shall cause the cities to be inhabited, and shall repair the ruinous places,", "bbe": "This is what the Lord has said: In the day when I make you clean from all your evil-doings I will let the towns be peopled and there will be building on the waste places.", "geneva": "Thus sayth the Lord God, What time as I shall haue clensed you from all your iniquities, I will cause you to dwel in the cities, and the desolate places shalbe builded.", "wycliffe": "The Lord God seith these thingis, In the dai in which Y schal clense you fro alle youre wickidnessis, and Y schal make citees to be enhabitid, and Y schal reparele ruynouse thingis,", "rotherham": "Thus saith My Lord, Yahweh, In the day when I cleanse you, from all your iniquities, Then will I cause the cities to be inhabited, And the waste places shall be built;", "darby": "Thus saith the Lord Jehovah: In the day that I shall cleanse you from all your iniquities I will also cause the cities to be inhabited, and the waste places shall be builded.", "twenty": "", "jps": "Thus saith the L-rd GOD: In the day that I cleanse you from all your iniquities, I will cause the cities to be inhabited, and the waste places shall be builded.", "acv": "Thus says the lord Jehovah: In the day that I cleanse you from all your iniquities, I will cause the cities to be inhabited, and the waste places shall be built.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: In the day when I shall cleanse you from all your iniquities, then will I cause the cities to be inhabited, and the waste places to be rebuilt;", "webster": "Thus saith the Lord GOD; In the day that I shall have cleansed you from all your iniquities I will also cause [you] to dwell in the cities, and the wastes shall be built.", "vulgate": "haec dicit Dominus Deus in die qua mundavero vos ex omnibus iniquitatibus vestris et habitari fecero urbes et instauravero ruinosa;", "brenton": "Thus saith the Lord God; In the day wherein I shall cleanse you from all your iniquities I will also cause the cities to be inhabited, and the waste places shall be built upon:"}}, {"v": 34, "ref": "36:34", "o": "וְ/הָ/אָ֥רֶץ הַ/נְּשַׁמָּ֖ה תֵּֽעָבֵ֑ד תַּ֚חַת אֲשֶׁ֣ר הָיְתָ֣ה שְׁמָמָ֔ה לְ/עֵינֵ֖י כָּל עוֹבֵֽר", "en": {"kjv": "And the desolate land shall be tilled, whereas it lay desolate in the sight of all that passed by.", "web": "The land that was desolate shall be tilled, whereas it was a desolation in the sight of all who passed by.", "bsb": "The desolate land will be cultivated instead of lying desolate in the sight of all who pass through.", "asv": "And the land that was desolate shall be tilled, whereas it was a desolation in the sight of all that passed by.", "ylt": "And the desolate land is tilled, Instead of which it was a desolation before the eyes of every passer by,", "dra": "And the desolate land shall be tilled, which before was waste in the sight of all that passed by,", "bbe": "And the land which was waste will be farmed, in place of being a waste in the eyes of everyone who went by.", "geneva": "And the desolate land shalbe tilled, whereas it lay waste in the sight of all that passed by.", "wycliffe": "and the desert lond schal be tilid, that was sum tyme desolat, bifor the iyen of ech weiegoere,", "rotherham": "And the land that was made desolate shall be tilled,— Whereas it was a desolation, before the eyes of every passer-by;", "darby": "And the desolate land shall be tilled, whereas it was a desolation in the sight of all that passed by.", "twenty": "", "jps": "And the land that was desolate shall be tilled, whereas it was a desolation in the sight of all that passed by.", "acv": "And the land that was desolate shall be tilled, whereas it was a desolation in the sight of all who passed by.", "anderson": "", "haweis": "", "noyes": "and the desolate land shall be tilled, whereas it lay desolate in the sight of all that passed by.", "webster": "And the desolate land shall be tilled, whereas it lay desolate in the sight of all that passed by.", "vulgate": "et terra deserta fuerit exculta quae quondam erat desolata in oculis omnis viatoris;", "brenton": "and the desolate land shall be cultivated, whereas it was desolate in the eyes of every one that passed by."}}, {"v": 35, "ref": "36:35", "o": "וְ/אָמְר֗וּ הָ/אָ֤רֶץ הַלֵּ֨זוּ֙ הַ/נְּשַׁמָּ֔ה הָיְתָ֖ה כְּ/גַן עֵ֑דֶן וְ/הֶ/עָרִ֧ים הֶ/חֳרֵב֛וֹת וְ/הַֽ/נְשַׁמּ֥וֹת וְ/הַ/נֶּהֱרָס֖וֹת בְּצוּר֥וֹת יָשָֽׁבוּ", "en": {"kjv": "And they shall say, This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities are become fenced, and are inhabited.", "web": "They shall say, This land that was desolate has become like the garden of Eden; and the waste and desolate and ruined cities are fortified and inhabited.", "bsb": "Then they will say, ‘This land that was desolate has become like the garden of Eden. The cities that were once ruined, desolate, and destroyed are now fortified and inhabited.’", "asv": "And they shall say, This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities are fortified and inhabited.", "ylt": "And they have said: This land, that was desolated, Hath been as the garden of Eden, And the cities--the wasted, And the desolated, and the broken down, Fenced places have remained.", "dra": "They shall say: This land that was untilled is become as a garden of pleasure: and the cities that were abandoned, and desolate, and destroyed, are peopled and fenced.", "bbe": "And they will say, This land which was waste has become like the garden of Eden; and the towns which were unpeopled and wasted and pulled down are walled and peopled.", "geneva": "For they sayd, This waste land was like the garden of Eden, and these waste and desolate and ruinous cities were strong, and were inhabited.", "wycliffe": "thei schulen seie, Thilke lond vntilid is maad as a gardyn of likyng, and citees forsakun and destitute and vndur myned saten maad strong; and hethene men,", "rotherham": "And they shall say, This land that was made desolate hath become like the garden of Eden,- And the cities that were waste and deserted and thrown down, now fenced, are inhabited;", "darby": "And they shall say, This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities [are] fortified [and] inhabited.", "twenty": "", "jps": "And they shall say: This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities are fortified and inhabited.", "acv": "And they shall say, This land that was desolate has become like the garden of Eden. And the waste and desolate and ruined cities are fortified and inhabited.", "anderson": "", "haweis": "", "noyes": "Then shall it be said, \"This land, that was desolate, is become as the garden of Eden; and the waste and desolate and ruined cities are become fenced, and are inhabited.\"", "webster": "And they shall say, This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities [are become] fortified, [and] are inhabited.", "vulgate": "dicent terra illa inculta facta est ut hortus voluptatis et civitates desertae et destitutae atque suffossae munitae sederunt;", "brenton": "And they shall say, That desolate land is become like a garden of delight; and the waste and desolate and ruined cities are inhabited."}}, {"v": 36, "ref": "36:36", "o": "וְ/יָדְע֣וּ הַ/גּוֹיִ֗ם אֲשֶׁ֣ר יִֽשָּׁאֲרוּ֮ סְבִיבוֹתֵי/כֶם֒ כִּ֣י אֲנִ֣י יְהוָ֗ה בָּנִ֨יתִי֙ הַ/נֶּ֣הֱרָס֔וֹת נָטַ֖עְתִּי הַ/נְּשַׁמָּ֑ה אֲנִ֥י יְהוָ֖ה דִּבַּ֥רְתִּי וְ/עָשִֽׂיתִי", "en": {"kjv": "Then the heathen that are left round about you shall know that I the Lord build the ruined places, and plant that that was desolate: I the Lord have spoken it, and I will do it.", "web": "Then the nations that are left around you shall know that I, Yahweh, have built the ruined places, and planted that which was desolate: I, Yahweh, have spoken it, and I will do it.", "bsb": "Then the nations around you that remain will know that I, the LORD, have rebuilt what was destroyed, and I have replanted what was desolate. I, the LORD, have spoken, and I will do it.", "asv": "Then the nations that are left round about you shall know that I, Jehovah, have builded the ruined places, and planted that which was desolate: I, Jehovah, have spoken it, and I will do it.", "ylt": "And known have the nations who are left round about you, That I Jehovah have built the thrown down, I have planted the desolated: I Jehovah have spoken, and I have done it .", "dra": "And the nations, that shall be left round about you, shall know that I the Lord have built up what was destroyed, and planted what was desolate, that I the Lord have spoken and done it.", "bbe": "Then the rest of the nations round about you will be certain that I the Lord am the builder of the places which were pulled down and the planter of that which was waste: I the Lord have said it, and I will do it.", "geneva": "Then the residue of the heathen that are left round about you, shall know that I the Lord builde the ruinous places, and plant the desolate places: I the Lord haue spoken it, and wil do it.", "wycliffe": "whiche euer ben left in youre cumpas, schulen wite, that Y the Lord haue bildid distried thingis, and Y haue plauntid vntilid thingis; Y the Lord spak, and Y dide.", "rotherham": "So shall the nations that may be left remaining round about you know that, I Yahweh— Have built that which was thrown down, and Have planted that which was made desolate,— I Yahweh, have spoken and performed.", "darby": "And the nations that shall be left round about you shall know that I Jehovah build the ruined places [and] plant that which was desolate: I Jehovah have spoken, and I will do [it].", "twenty": "", "jps": "Then the nations that are left round about you shall know that I HaShem have builded the ruined places, and planted that which was desolate; I HaShem have spoken it, and I will do it.", "acv": "Then the nations that are left round about you shall know that I, Jehovah, have built the ruined places, and planted that which was desolate. I, Jehovah, have spoken it, and I will do it.", "anderson": "", "haweis": "", "noyes": "Then the nations that are left around you shall know that I, Jehovah, have built that which was ruined, and planted that which was desolate. I, Jehovah, have spoken it, and I will do it.", "webster": "Then the heathen that are left around you shall know that I the LORD build the ruined [places], [and] plant that which was desolate: I the LORD have spoken [it], and I will do [it].", "vulgate": "et scient gentes quaecumque derelictae fuerint in circuitu vestro quia ego Dominus aedificavi dissipata plantavique inculta ego Dominus locutus sum et fecerim;", "brenton": "And the nations, as many as shall have been left round about you, shall know that I the Lord have built the ruined cities and planted the waste lands: I the Lord have spoken, and will do it."}}, {"v": 37, "ref": "36:37", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה ע֗וֹד זֹ֛את אִדָּרֵ֥שׁ לְ/בֵֽית יִשְׂרָאֵ֖ל לַ/עֲשׂ֣וֹת לָ/הֶ֑ם אַרְבֶּ֥ה אֹתָ֛/ם כַּ/צֹּ֖אן אָדָֽם", "en": {"kjv": "Thus saith the Lord God; I will yet for this be enquired of by the house of Israel, to do it for them; I will increase them with men like a flock.", "web": "Thus says the Lord Yahweh: For this, moreover, will I be inquired of by the house of Israel, to do it for them: I will increase them with men like a flock.", "bsb": "This is what the Lord GOD says: Once again I will hear the plea of the house of Israel and do for them this: I will multiply their people like a flock.", "asv": "Thus saith the Lord Jehovah: For this, moreover, will I be inquired of by the house of Israel, to do it for them: I will increase them with men like a flock.", "ylt": "Thus said the Lord Jehovah: Yet this I am required, By the house of Israel to do to them, I multiply them as a flock of men,", "dra": "Thus saith the Lord God: Moreover in this shall the house of Israel find me, that I will do it for them: I will multiply them as a flock of men,", "bbe": "This is what the Lord has said: The children of Israel will again make prayer to me for this, that I may do it for them; I will make them increased with men like a flock.", "geneva": "Thus saith the Lord God, I will yet for this be sought of ye house of Israel, to performe it vnto them: I wil encrease them with men like a flocke.", "wycliffe": "The Lord God seith these thingis, Yit in this thing the hous of Israel schulen fynde me, that Y do to hem; Y schal multiplie hem as the floc of men, as an hooli floc,", "rotherham": "Thus, saith My Lord Yahweh, Even yet—for this, will I be prevailed upon by the house of Israel to work for them,— I will multiply them-Like a flock—with men:", "darby": "Thus saith the Lord Jehovah: I will yet for this be inquired of by the house of Israel, to do it unto them; I will increase them with men like a flock.", "twenty": "", "jps": "Thus saith the L-rd GOD: I will yet for this be inquired of by the house of Israel, to do it for them; I will increase them with men like a flock.", "acv": "Thus says the lord Jehovah: For this, moreover, I will be inquired of by the house of Israel, to do it for them. I will increase them with men like a flock.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Yet will I listen to the house of Israel, and do this for them. I will increase", "webster": "Thus saith the Lord GOD; I will yet [for] this be inquired of by the house of Israel, to do [it] for them; I will increase them with men like a flock.", "vulgate": "haec dicit Dominus Deus adhuc in hoc invenient me domus Israhel ut faciam eis multiplicabo eos sicut gregem hominum;", "brenton": "Thus saith the Lord God; Yet for this will I be sought by the house of Israel, to establish them; I will multiply them even men as sheep;"}}, {"v": 38, "ref": "36:38", "o": "כְּ/צֹ֣אן קָֽדָשִׁ֗ים כְּ/צֹ֤אן יְרוּשָׁלִַ֨ם֙ בְּ/מ֣וֹעֲדֶ֔י/הָ כֵּ֤ן תִּהְיֶ֨ינָה֙ הֶ/עָרִ֣ים הֶ/חֳרֵב֔וֹת מְלֵא֖וֹת צֹ֣אן אָדָ֑ם וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "As the holy flock, as the flock of Jerusalem in her solemn feasts; so shall the waste cities be filled with flocks of men: and they shall know that I am the Lord.", "web": "As the flock for sacrifice, as the flock of Jerusalem in her appointed feasts, so shall the waste cities be filled with flocks of men; and they shall know that I am Yahweh.", "bsb": "Like the numerous flocks for sacrifices at Jerusalem during her appointed feasts, so the ruined cities will be filled with flocks of people. Then they will know that I am the LORD.”", "asv": "As the flock for sacrifice, as the flock of Jerusalem in her appointed feasts, so shall the waste cities be filled with flocks of men; and they shall know that I am Jehovah.", "ylt": "As a flock of holy ones, as a flock of Jerusalem, In her appointed seasons, So are the waste cities full of flocks of men, And they have known that I am Jehovah!'", "dra": "As a holy flock, as the flock of Jerusalem in her solemn feasts: so shall the waste cities be full of flocks of men: and they shall know that I am the Lord.", "bbe": "Like sheep for the offerings, like the sheep of Jerusalem at her fixed feasts, so the unpeopled towns will be made full of men: and they will be certain that I am the Lord.", "geneva": "As the holy flocke, as the flocke of Ierusalem in their solemne feastes, so shall the desolate cities be filled with flockes of men, and they shall know, that I am the Lord.", "wycliffe": "as the floc of Jerusalem in the solempnytees therof, so the citees that ben forsakun, schulen be fulle of the flockis of men; and thei schulen wite, that Y am the Lord.", "rotherham": "Like a flock of holy offerings Like the flock of Jerusalem in her appointed feasts, So, shall the waste cities be filled with flocks of men,- And they shall know that, I, am Yahweh.", "darby": "As the holy flock, as the flock of Jerusalem in her set feasts, so shall the waste cities be filled with flocks of men: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "As the flock for sacrifice, as the flock of Jerusalem in her appointed seasons, so shall the waste cities be filled with flocks of men; and they shall know that I am HaShem.'", "acv": "As the flock for sacrifice, as the flock of Jerusalem in her appointed feasts, so shall the waste cities be filled with flocks of men. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "them with men like a flock; as the holy flock, as the flock of Jerusalem in her solemn feasts; so shall the waste cities be filled with flocks of men; and they shall know that I am Jehovah.", "webster": "As the holy flock, as the flock of Jerusalem in her solemn feasts; so shall the waste cities be filled with flocks of men: and they shall know that I [am] the LORD.", "vulgate": "ut gregem sanctum ut gregem Hierusalem in sollemnitatibus eius sic erunt civitates desertae plenaeque gregibus hominum et scient quia ego Dominus;", "brenton": "as holy sheep, as the sheep of Jerusalem in her feasts; thus shall the desert cities be full of flocks of men: and they shall know that I am the Lord."}}]}, {"c": 37, "verses": [{"v": 1, "ref": "37:1", "o": "הָיְתָ֣ה עָלַ/י֮ יַד יְהוָה֒ וַ/יּוֹצִאֵ֤/נִי בְ/ר֨וּחַ֙ יְהוָ֔ה וַ/יְנִיחֵ֖/נִי בְּ/ת֣וֹךְ הַ/בִּקְעָ֑ה וְ/הִ֖יא מְלֵאָ֥ה עֲצָמֽוֹת", "en": {"kjv": "The hand of the Lord was upon me, and carried me out in the spirit of the Lord, and set me down in the midst of the valley which was full of bones,", "web": "The hand of Yahweh was on me, and he brought me out in the Spirit of Yahweh, and set me down in the midst of the valley; and it was full of bones.", "bsb": "The hand of the LORD was upon me, and He brought me out by His Spirit and set me down in the middle of the valley, and it was full of bones.", "asv": "The hand of Jehovah was upon me, and he brought me out in the Spirit of Jehovah, and set me down in the midst of the valley; and it was full of bones.", "ylt": "There hath been upon me a hand of Jehovah, and He taketh me forth in the Spirit of Jehovah, and doth place me in the midst of the valley, and it is full of bones,", "dra": "The hand of the Lord was upon me, and brought me forth in the spirit of the Lord: and set me down in the midst of a plain that was full of bones.", "bbe": "The hand of the Lord had been on me, and he took me out in the spirit of the Lord and put me down in the middle of the valley; and it was full of bones;", "geneva": "The hand of the Lord was vpon me, and caryed me out in ye spirit of ye Lord, and set me downe in ye mids of the field, which was full of bones.", "wycliffe": "The hond of the Lord was maad on me, and ledde me out in the spirit of the Lord; and he lefte me in the myddis of a feeld that was ful of boonys;", "rotherham": "The hand of Yahweh, being upon me, he carried me forth in the spirit of Yahweh, and set me down in the midst of a plain,—and the same was full of bones;", "darby": "The hand of Jehovah was upon me, and Jehovah carried me out in the Spirit, and set me down in the midst of a valley; and it was full of bones.", "twenty": "", "jps": "The hand of HaShem was upon me, and HaShem carried me out in a spirit, and set me down in the midst of the valley, and it was full of bones;", "acv": "The hand of Jehovah was upon me, and he brought me out in the Spirit of Jehovah, and set me down in the midst of the valley, and it was full of bones.", "anderson": "", "haweis": "", "noyes": "The hand of Jehovah was upon me, and he carried me out in the spirit of Jehovah, and set me in the midst of a valley, which was full of bones,", "webster": "The hand of the LORD was upon me, and carried me out in the spirit of the LORD, and set me down in the midst of the valley which [was] full of bones,", "vulgate": "facta est super me manus Domini et eduxit me in spiritu Domini et dimisit me in medio campi qui erat plenus ossibus;", "brenton": "And the hand of the Lord came upon me, and the Lord brought me forth by the Spirit, and set me in the midst of the plain, and it was full of human bones."}}, {"v": 2, "ref": "37:2", "o": "וְ/הֶעֱבִירַ֥/נִי עֲלֵי/הֶ֖ם סָבִ֣יב סָבִ֑יב וְ/הִנֵּ֨ה רַבּ֤וֹת מְאֹד֙ עַל פְּנֵ֣י הַ/בִּקְעָ֔ה וְ/הִנֵּ֖ה יְבֵשׁ֥וֹת מְאֹֽד", "en": {"kjv": "And caused me to pass by them round about: and, behold, there were very many in the open valley; and, lo, they were very dry.", "web": "He caused me to pass by them all around: and behold, there were very many in the open valley; and behold, they were very dry.", "bsb": "He led me all around among them, and I saw a great many bones on the floor of the valley, and indeed, they were very dry.", "asv": "And he caused me to pass by them round about: and, behold, there were very many in the open valley; and, lo, they were very dry.", "ylt": "and He causeth me to pass over by them, all round about, and lo, very many are on the face of the valley, and lo, very dry.", "dra": "And he led me about through them on every side: now they were very many upon the face of the plain, and they were exceeding dry.", "bbe": "And he made me go past them round about: and I saw that there was a very great number of them on the face of the wide valley, and they were very dry.", "geneva": "And he led me round about by them, and beholde, they were very many in the open fielde, and lo, they were very drie.", "wycliffe": "and he ledde me aboute bi tho in cumpas. Forsothe tho weren ful manye on the face of the feeld, and drie greetli.", "rotherham": "and he caused me to pass near them. round about on every side,—and lo! they were very many on the face of the plain, and lo! they were very dry.", "darby": "And he caused me to pass by them round about; and behold, there were very many in the open valley; and behold, they were very dry.", "twenty": "", "jps": "and He caused me to pass by them round about, and, behold, there were very many in the open valley; and, lo, they were very dry.", "acv": "And he caused me to pass by them round about. And, behold, there were very many in the open valley, and, lo, they were very dry.", "anderson": "", "haweis": "", "noyes": "and caused me to pass by them round about; and behold, there were very many upon the surface of the valley, and lo, they were very dry.", "webster": "And caused me to pass by them around: and behold, [there were] very many in the open valley; and lo, [they were] very dry.", "vulgate": "et circumduxit me per ea in gyro erant autem multa valde super faciem campi siccaque vehementer;", "brenton": "And he led me round about them every way: and, behold, there were very many on the face of the plain, very dry."}}, {"v": 3, "ref": "37:3", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י בֶּן אָדָ֕ם הֲ/תִחְיֶ֖ינָה הָ/עֲצָמ֣וֹת הָ/אֵ֑לֶּה וָ/אֹמַ֕ר אֲדֹנָ֥/י יְהוִ֖ה אַתָּ֥ה יָדָֽעְתָּ", "en": {"kjv": "And he said unto me, Son of man, can these bones live? And I answered, O Lord God, thou knowest.", "web": "He said to me, Son of man, can these bones live? I answered, Lord Yahweh, you know.", "bsb": "Then He asked me, “Son of man, can these bones come to life?” “O Lord GOD,” I replied, “only You know.”", "asv": "And he said unto me, Son of man, can these bones live? And I answered, O Lord Jehovah, thou knowest.", "ylt": "And He saith unto me, `Son of man, do these bones live?' And I say, `O Lord Jehovah, Thou--Thou hast known.'", "dra": "And he said to me: Son of man, dost thou think these bones shall live and I answered: O Lord God, thou knowest.", "bbe": "And he said to me, Son of man, is it possible for these bones to come to life? And I made answer, and said, It is for you to say, O Lord.", "geneva": "And he sayde vnto me, Sonne of man, can these bones liue? And I answered, O Lord God, thou knowest.", "wycliffe": "And he seide to me, Gessist thou, sone of man, whether these boonys schulen lyue? And Y seide, Lord God, thou wost.", "rotherham": "Then said he unto me, Son of man. Can these bones, live? And I said My Lord Yahweh, thou, knowest!", "darby": "And he said unto me, Son of man, Shall these bones live? And I said, Lord Jehovah, thou knowest.", "twenty": "", "jps": "And He said unto me: 'Son of man, can these bones live?' And I answered: 'O L-rd GOD, Thou knowest.'", "acv": "And he said to me, Son of man, can these bones live? And I answered, O lord Jehovah, thou know.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, can these bones live? And I answered, O Lord Jehovah, thou knowest!", "webster": "And he said to me, Son of man, can these bones live? and I answered, O Lord GOD, thou knowest.", "vulgate": "et dixit ad me fili hominis putasne vivent ossa ista et dixi Domine Deus tu nosti;", "brenton": "And he said to me, Son of man, will these bones live? and I said, O Lord God, thou knowest this."}}, {"v": 4, "ref": "37:4", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י הִנָּבֵ֖א עַל הָ/עֲצָמ֣וֹת הָ/אֵ֑לֶּה וְ/אָמַרְתָּ֣ אֲלֵי/הֶ֔ם הָ/עֲצָמוֹת֙ הַ/יְבֵשׁ֔וֹת שִׁמְע֖וּ דְּבַר יְהוָֽה", "en": {"kjv": "Again he said unto me, Prophesy upon these bones, and say unto them, O ye dry bones, hear the word of the Lord.", "web": "Again he said to me, Prophesy over these bones, and tell them, you dry bones, hear Yahweh’s word.", "bsb": "And He said to me, “Prophesy concerning these bones and tell them, ‘Dry bones, hear the word of the LORD!", "asv": "Again he said unto me, Prophesy over these bones, and say unto them, O ye dry bones, hear the word of Jehovah.", "ylt": "And He saith unto me, `Prophesy concerning these bones, and thou hast said unto them: O dry bones, hear a word of Jehovah:", "dra": "And he said to me: Prophesy concerning these bones; and say to them: Ye dry bones, hear the word of the Lord.", "bbe": "And again he said to me, Be a prophet to these bones, and say to them, O you dry bones, give ear to the word of the Lord.", "geneva": "Againe he sayde vnto me, Prophecie vpon these bones and say vnto them, O ye dry bones, heare the word of the Lord.", "wycliffe": "And he seide to me, Profesie thou of these boonys; and thou schalt seie to tho, Ye drie boonys, here the word of the Lord.", "rotherham": "Then said he unto me, Prophesy, over these bones,—and thou shalt say unto them, Ye bones so dry! hear ye the word of Yahweh!", "darby": "And he said unto me, Prophesy over these bones, and say unto them, Ye dry bones, hear the word of Jehovah.", "twenty": "", "jps": "Then He said unto me: 'Prophesy over these bones, and say unto them: O ye dry bones, hear the word of HaShem:", "acv": "Again he said to me, Prophesy over these bones, and say to them, O ye dry bones, hear the word of Jehovah.", "anderson": "", "haweis": "", "noyes": "Then he said to me, Prophesy to these dry bones, and say to them, O ye dry bones, hear the word of Jehovah!", "webster": "Again he said to me, Prophesy upon these bones, and say to them, O ye dry bones, hear the word of the LORD.", "vulgate": "et dixit ad me vaticinare de ossibus istis et dices eis ossa arida audite verbum Domini;", "brenton": "And he said to me, Prophesy upon these bones, and thou shalt say to them, Ye dry bones, hear the word of the Lord."}}, {"v": 5, "ref": "37:5", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה לָ/עֲצָמ֖וֹת הָ/אֵ֑לֶּה הִנֵּ֨ה אֲנִ֜י מֵבִ֥יא בָ/כֶ֛ם ר֖וּחַ וִ/חְיִיתֶֽם", "en": {"kjv": "Thus saith the Lord God unto these bones; Behold, I will cause breath to enter into you, and ye shall live:", "web": "Thus says the Lord Yahweh to these bones: Behold, I will cause breath to enter into you, and you shall live.", "bsb": "This is what the Lord GOD says to these bones: I will cause breath to enter you, and you will come to life.", "asv": "Thus saith the Lord Jehovah unto these bones: Behold, I will cause breath to enter into you, and ye shall live.", "ylt": "Thus said the Lord Jehovah to these bones: Lo, I am bringing into you a spirit, and ye have lived,", "dra": "Thus saith the Lord God to these bones: Behold, I will send spirit into you, and you shall live.", "bbe": "This is what the Lord has said to these bones: See, I will make breath come into you so that you may come to life;", "geneva": "Thus saith the Lord God vnto these bones, Behold, I wil cause breath to enter into you, and ye shall liue.", "wycliffe": "The Lord God seith these thingis to these boonys, Lo! Y schal sende in to you a spirit, and ye schulen lyue.", "rotherham": "Thus saith My Lord Yahweh, Unto these bones,— Lo! I am about to bring into you— spirit, and ye shall live;", "darby": "Thus saith the Lord Jehovah unto these bones: Behold, I will cause breath to enter into you, and ye shall live.", "twenty": "", "jps": "Thus saith the L-rd GOD unto these bones: Behold, I will cause breath to enter into you, and ye shall live.", "acv": "Thus says the lord Jehovah to these bones: Behold, I will cause breath to enter into you, and ye shall live.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah to these bones: Behold, I will cause breath to enter into you, and ye shall live;", "webster": "Thus saith the Lord GOD to these bones; Behold, I will cause breath to enter into you, and ye shall live:", "vulgate": "haec dicit Dominus Deus ossibus his ecce ego intromittam in vos spiritum et vivetis;", "brenton": "Thus saith the Lord to these bones; Behold, I will bring upon you the breath of life:"}}, {"v": 6, "ref": "37:6", "o": "וְ/נָתַתִּי֩ עֲלֵי/כֶ֨ם גִּדִ֜ים וְֽ/הַעֲלֵתִ֧י עֲלֵי/כֶ֣ם בָּשָׂ֗ר וְ/קָרַמְתִּ֤י עֲלֵי/כֶם֙ ע֔וֹר וְ/נָתַתִּ֥י בָ/כֶ֛ם ר֖וּחַ וִ/חְיִיתֶ֑ם וִ/ידַעְתֶּ֖ם כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live; and ye shall know that I am the Lord.", "web": "I will lay sinews on you, and will bring up flesh on you, and cover you with skin, and put breath in you, and you shall live; and you shall know that I am Yahweh.", "bsb": "I will attach tendons to you and make flesh grow upon you and cover you with skin. I will put breath within you so that you will come to life. Then you will know that I am the LORD.’”", "asv": "And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live; and ye shall know that I am Jehovah.", "ylt": "and I have given on you sinews, and cause flesh to come up upon you, and covered you over with skin, and given in you a spirit, and ye have lived, and ye have known that I am Jehovah.'", "dra": "And I will lay sinews upon you, and will cause flesh to grow over you, and will cover you with skin: and I will give you spirit and you shall live, and you shall know that I am the Lord.", "bbe": "And I will put muscles on you and make flesh come on you, and put skin over you, and breath into you, so that you may have life; and you will be certain that I am the Lord.", "geneva": "And I will lay sinewes vpon you, and make flesh growe vpon you, and couer you with skinne, and put breath in you, that ye may liue, and yee shall know that I am the Lord.", "wycliffe": "And Y schal yyue synewis on you, and Y schal make fleischis to wexe on you, and Y schal stretche forth aboue a skyn in you, and Y schal yyue a spirit to you, and ye schulen lyue; and ye schulen wite, that Y am the Lord.", "rotherham": "Yea I will lay upon you—sinews, And bring up over you flesh. And cover over you—skin, And put in you—spirit And ye shall live, Then shall ye know that I, am Yahweh.", "darby": "And I will put sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live: and ye shall know that I [am] Jehovah.", "twenty": "", "jps": "And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live; and ye shall know that I am HaShem.'", "acv": "And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live. And ye shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "and I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath into you, and ye shall live; and ye shall know that I am Jehovah.", "webster": "And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live; and ye shall know that I [am] the LORD.", "vulgate": "et dabo super vos nervos et succrescere faciam super vos carnes et superextendam in vobis cutem et dabo vobis spiritum et vivetis et scietis quia ego Dominus;", "brenton": "and I will lay sinews upon you, and will bring up flesh upon you, and will spread skin upon you, and will put my Spirit into you, and ye shall live; and ye shall know that I am the Lord."}}, {"v": 7, "ref": "37:7", "o": "וְ/נִבֵּ֖אתִי כַּ/אֲשֶׁ֣ר צֻוֵּ֑יתִי וַֽ/יְהִי ק֤וֹל כְּ/הִנָּֽבְאִ/י֙ וְ/הִנֵּה רַ֔עַשׁ וַ/תִּקְרְב֣וּ עֲצָמ֔וֹת עֶ֖צֶם אֶל עַצְמֽ/וֹ", "en": {"kjv": "So I prophesied as I was commanded: and as I prophesied, there was a noise, and behold a shaking, and the bones came together, bone to his bone.", "web": "So I prophesied as I was commanded: and as I prophesied, there was a noise, and behold, an earthquake; and the bones came together, bone to its bone.", "bsb": "So I prophesied as I had been commanded. And as I prophesied, there was suddenly a noise, a rattling, and the bones came together, bone to bone.", "asv": "So I prophesied as I was commanded: and as I prophesied, there was a noise, and, behold, an earthquake; and the bones came together, bone to its bone.", "ylt": "And I have prophesied as I have been commanded, and there is a noise, as I am prophesying, and lo, a rushing, and draw near do the bones, bone unto its bone.", "dra": "And I prophesied as he had commanded me: and as I prophesied there was a noise, and behold a commotion: and the bones came together, each one, its joint.", "bbe": "So I gave the word as I was ordered: and at my words there was a shaking of the earth, and the bones came together, bone to bone.", "geneva": "So I prophecied, as I was commanded: and as I prophecied, there was a noyse, and beholde, there was a shaking, and the bones came together, bone to his bone.", "wycliffe": "And Y profesiede, as he comaundide to me; forsothe a sown was maad, while Y profesiede, and lo! a stiryng togidere, and boonys camen to boonys, ech to his ioynture.", "rotherham": "And when I prophesied as I was commanded, then was there a noise, as I prophesied and lo! a rattling, and the bones came near, each bone unto its own bone.", "darby": "And I prophesied as I was commanded; and as I prophesied, there was a noise, and behold a rustling, and the bones came together, bone to its bone.", "twenty": "", "jps": "So I prophesied as I was commanded; and as I prophesied, there was a noise, and behold a commotion, and the bones came together, bone to its bone.", "acv": "So I prophesied as I was commanded. And as I prophesied, there was a noise, and, behold, an earthquake, and the bones came together, bone to its bone.", "anderson": "", "haweis": "", "noyes": "So I prophesied, as I was commanded; and as I prophesied, a voice was heard, and behold, a shaking, and the bones came together, bone to its bone.", "webster": "So I prophesied as I was commanded: and as I prophesied, there was a noise, and behold a shaking, and the bones came together, bone to his bone.", "vulgate": "et prophetavi sicut praeceperat mihi factus est autem sonitus prophetante me et ecce commotio et accesserunt ossa ad ossa unumquodque ad iuncturam suam;", "brenton": "So I prophesied as the Lord commanded me: and it came to pass while I was prophesying, that, behold, there was a shaking, and the bones approached each one to his joint."}}, {"v": 8, "ref": "37:8", "o": "וְ/רָאִ֜יתִי וְ/הִנֵּֽה עֲלֵי/הֶ֤ם גִּדִים֙ וּ/בָשָׂ֣ר עָלָ֔ה וַ/יִּקְרַ֧ם עֲלֵי/הֶ֛ם ע֖וֹר מִ/לְ/מָ֑עְלָ/ה וְ/ר֖וּחַ אֵ֥ין בָּ/הֶֽם", "en": {"kjv": "And when I beheld, lo, the sinews and the flesh came up upon them, and the skin covered them above: but there was no breath in them.", "web": "I saw, and, behold, there were sinews on them, and flesh came up, and skin covered them above; but there was no breath in them.", "bsb": "As I looked on, tendons appeared on them, flesh grew, and skin covered them; but there was no breath in them.", "asv": "And I beheld, and, lo, there were sinews upon them, and flesh came up, and skin covered them above; but there was no breath in them.", "ylt": "And I beheld, and lo, on them are sinews, and flesh hath come up, and cover them doth skin over above--and spirit there is none in them.", "dra": "And I saw, and behold the sinews, and the flesh came up upon them: and the skin was stretched out over them, but there was no spirit in them.", "bbe": "And looking I saw that there were muscles on them and flesh came up, and they were covered with skin: but there was no breath in them.", "geneva": "And when I beheld, loe, the sinewes, and the flesh grewe vpon them, and aboue, the skinne couered them, but there was no breath in them.", "wycliffe": "And Y siy and lo! synewis and fleischis `wexeden vpon tho, and skyn was stretchid forth aboue in hem, and tho hadden no spirit.", "rotherham": "And when I looked, then lo! upon them were sinews, and flesh had come up, and there had spread over them skin above, but spirit, was there none within them.", "darby": "And I looked, and behold, sinews and flesh came up upon them, and the skin covered them over; but there was no breath in them.", "twenty": "", "jps": "And I beheld, and, lo, there were sinews upon them, and flesh came up, and skin covered them above; but there was no breath in them.", "acv": "And I beheld, and, lo, there were sinews upon them, and flesh came up, and skin covered them above, but there was no breath in them.", "anderson": "", "haweis": "", "noyes": "And when I looked, behold, there were sinews upon them, and the flesh grew, and the skin covered them above; but there was no breath in them.", "webster": "And when I beheld, lo, the sinews and the flesh came up upon them, and the skin covered them above: but [there was] no breath in them.", "vulgate": "et vidi et ecce super ea nervi et carnes ascenderunt et extenta est in eis cutis desuper et spiritum non habebant;", "brenton": "And I looked, and behold, sinews and flesh grew upon them, and skin came upon them above: but there was not breath in them."}}, {"v": 9, "ref": "37:9", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י הִנָּבֵ֖א אֶל הָ/ר֑וּחַ הִנָּבֵ֣א בֶן אָ֠דָם וְ/אָמַרְתָּ֨ אֶל הָ/ר֜וּחַ כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה מֵ/אַרְבַּ֤ע רוּחוֹת֙ בֹּ֣אִי הָ/ר֔וּחַ וּ/פְחִ֛י בַּ/הֲרוּגִ֥ים הָ/אֵ֖לֶּה וְ/יִֽחְיֽוּ", "en": {"kjv": "Then said he unto me, Prophesy unto the wind, prophesy, son of man, and say to the wind, Thus saith the Lord God; Come from the four winds, O breath, and breathe upon these slain, that they may live.", "web": "Then he said to me, Prophesy to the wind, prophesy, son of man, and tell the wind, Thus says the Lord Yahweh: Come from the four winds, breath, and breathe on these slain, that they may live.", "bsb": "Then He said to me, “Prophesy to the breath; prophesy, son of man, and tell the breath that this is what the Lord GOD says: Come from the four winds, O breath, and breathe into these slain, so that they may live!”", "asv": "Then said he unto me, Prophesy unto the wind, prophesy, son of man, and say to the wind, Thus saith the Lord Jehovah: Come from the four winds, O breath, and breathe upon these slain, that they may live.", "ylt": "And He saith unto me: `Prophesy unto the Spirit, prophesy, son of man, and thou hast said unto the Spirit: Thus said the Lord Jehovah: From the four winds come in, O Spirit, and breathe on these slain, and they do live.'", "dra": "And he said to me: Prophesy to the spirit, prophesy, O son of man, and say to the spirit: Thus saith the Lord God: Come, spirit, from the four winds, and blow upon these slain, and let them live again.", "bbe": "And he said to me, Be a prophet to the wind, be a prophet, son of man, and say to the wind, The Lord has said: Come from the four winds, O wind, breathing on these dead so that they may come to life.", "geneva": "Then sayd he vnto me, Prophecie vnto the winde: prophecie, sonne of man, and say to the winde, Thus sayth the Lord God, Come from the foure windes, O breath, and breathe vpon these slayne, that they may liue.", "wycliffe": "And he seide to me, Profesie thou to the spirit, profesie thou, sone of man; and thou schalt seie to the spirit, The Lord God seith these thingis, Come, thou spirit, fro foure wyndis, and blowe thou on these slayn men, and lyue thei ayen.", "rotherham": "Then said he unto me, Prophesy unto the spirit, Prophesy, Son of man. and thou shalt say unto the spirit. Thus saith My Lord Yahweh- From the four winds, come thou, O spirit, And breathe into these slain That they may live.", "darby": "And he said unto me, Prophesy unto the wind, prophesy, son of man, and say to the wind, Thus saith the Lord Jehovah: Come from the four winds, O breath, and breathe upon these slain, that they may live.", "twenty": "", "jps": "Then said He unto me: 'Prophesy unto the breath, prophesy, son of man, and say to the breath: Thus saith the L-rd GOD: Come from the four winds, O breath, and breathe upon these slain, that they may live.'", "acv": "Then he said to me, Prophesy to the wind. Prophesy, son of man, and say to the wind, Thus says the lord Jehovah: Come from the four winds, O breath, and breathe upon these slain, that they may live.", "anderson": "", "haweis": "", "noyes": "Then said he to me, Prophesy to breath, prophesy, O son of man, and say to breath, Thus saith the Lord Jehovah: Come from the four winds, O breath, and breathe upon these slain, that they may live!", "webster": "Then said he to me, Prophesy to the wind, prophesy, son of man, and say to the wind, Thus saith the Lord GOD; Come from the four winds, O breath, and breathe upon these slain, that they may live.", "vulgate": "et dixit ad me vaticinare ad spiritum vaticinare fili hominis et dices ad spiritum haec dicit Dominus Deus a quattuor ventis veni spiritus et insufla super interfectos istos et revivescant;", "brenton": "And he said to me, Prophesy to the wind, prophesy, son of man, and say to the wind, Thus saith the Lord; Come from the four winds, and breathe upon these dead men, and let them live."}}, {"v": 10, "ref": "37:10", "o": "וְ/הִנַּבֵּ֖אתִי כַּ/אֲשֶׁ֣ר צִוָּ֑/נִי וַ/תָּבוֹא֩ בָ/הֶ֨ם הָ/ר֜וּחַ וַ/יִּֽחְי֗וּ וַ/יַּֽעַמְדוּ֙ עַל רַגְלֵי/הֶ֔ם חַ֖יִל גָּד֥וֹל מְאֹד מְאֹֽד", "en": {"kjv": "So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great army.", "web": "So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up on their feet, an exceedingly great army.", "bsb": "So I prophesied as He had commanded me, and the breath entered them, and they came to life and stood on their feet—a vast army.", "asv": "So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great army.", "ylt": "And I have prophesied as He commanded me, and the Spirit cometh into them, and they live, and stand on their feet--a very very great force.", "dra": "And I prophesied as he had commanded me: and the spirit came into them, and they lived: and they stood up upon their feet, an exceeding great army.", "bbe": "And I gave the word at his orders, and breath came into them, and they came to life and got up on their feet, a very great army.", "geneva": "So I prophecied as hee had commanded me: and the breath came into them, and they liued, and stood vp vpon their feete, an exceeding great armie.", "wycliffe": "And Y profesiede, as he comaundide to me; and the spirit entride in to tho boonys, and thei lyueden, and stoden on her feet, a ful greet oost.", "rotherham": "And when I prophesied as he commanded me, then came into them the spirit, and they lived and stood upon their feet, an exceeding great army.", "darby": "And I prophesied as he had commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great army.", "twenty": "", "jps": "So I prophesied as He commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great host.", "acv": "So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceedingly great army.", "anderson": "", "haweis": "", "noyes": "So I prophesied, as he commanded me; and the breath came into them, and they lived and stood on their feet, an exceedingly great host.", "webster": "So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great army.", "vulgate": "et prophetavi sicut praeceperat mihi et ingressus est in ea spiritus et vixerunt steteruntque super pedes suos exercitus grandis nimis valde;", "brenton": "So I prophesied as he commanded me, and the breath entered into them, and they lived, and stood upon their feet, a very great congregation."}}, {"v": 11, "ref": "37:11", "o": "וַ/יֹּאמֶר֮ אֵלַ/י֒ בֶּן אָדָ֕ם הָ/עֲצָמ֣וֹת הָ/אֵ֔לֶּה כָּל בֵּ֥ית יִשְׂרָאֵ֖ל הֵ֑מָּה הִנֵּ֣ה אֹמְרִ֗ים יָבְשׁ֧וּ עַצְמוֹתֵ֛י/נוּ וְ/אָבְדָ֥ה תִקְוָתֵ֖/נוּ נִגְזַ֥רְנוּ לָֽ/נוּ", "en": {"kjv": "Then he said unto me, Son of man, these bones are the whole house of Israel: behold, they say, Our bones are dried, and our hope is lost: we are cut off for our parts.", "web": "Then he said to me, Son of man, these bones are the whole house of Israel: behold, they say, Our bones are dried up, and our hope is lost; we are clean cut off.", "bsb": "Then He said to me, “Son of man, these bones are the whole house of Israel. Look, they are saying, ‘Our bones are dried up, and our hope has perished; we are cut off.’", "asv": "Then he said unto me, Son of man, these bones are the whole house of Israel: behold, they say, Our bones are dried up, and our hope is lost; we are clean cut off.", "ylt": "And He saith unto me, `Son of man, these bones are the whole house of Israel; lo, they are saying: Dried up have our bones, And perished hath our hope, We have been cut off by ourselves.", "dra": "And he said to me: Son of man: All these bones are the house of Israel: they say: Our bones are dried up, and our hope is lost, and we are cut off.", "bbe": "Then he said to me, Son of man, these bones are all the children of Israel: and see, they are saying, Our bones have become dry our hope is gone, we are cut off completely.", "geneva": "Then he sayd vnto me, Sonne of man, these bones are the whole house of Israel. Behold, they say, Our bones are dried, and our hope is gone, and we are cleane cut off.", "wycliffe": "And the Lord seide to me, Thou sone of man, alle these boonys is the hous of Israel; thei seien, Oure boonys drieden, and oure hope perischide, and we ben kit awei.", "rotherham": "Then said he unto me, Son of man. These bones, are all the house of Israel,— Lo! they are saying. Dried are our bones, and lost is our hope We are quite cut off!", "darby": "And he said unto me, Son of man, these bones are the whole house of Israel. Behold, they say, Our bones are dried, and our hope is lost: we are cut off!", "twenty": "", "jps": "Then He said unto me: 'Son of man, these bones are the whole house of Israel; behold, they say: Our bones are dried up, and our hope is lost; we are clean cut off.", "acv": "Then he said to me, Son of man, these bones are the whole house of Israel. Behold, they say, Our bones are dried up, and our hope is lost. We are clean cut off.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, these bones denote the whole house of Israel. Behold, they say, \"Our bones are dried, and our hope is lost, and we are cut off.\"", "webster": "Then he said to me, Son of man, these bones are the whole house of Israel: behold, they say, Our bones are dried, and our hope is lost: we are cut off for our parts.", "vulgate": "et dixit ad me fili hominis ossa haec universa domus Israhel est ipsi dicunt aruerunt ossa nostra et periit spes nostra et abscisi sumus;", "brenton": "And the Lord spoke to me, saying, Son of man, these bones are the whole house of Israel: and they say, Our bones are become dry, our hope has perished, we are quite spent."}}, {"v": 12, "ref": "37:12", "o": "לָ/כֵן֩ הִנָּבֵ֨א וְ/אָמַרְתָּ֜ אֲלֵי/הֶ֗ם כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִנֵּה֩ אֲנִ֨י פֹתֵ֜חַ אֶת קִבְרֽוֹתֵי/כֶ֗ם וְ/הַעֲלֵיתִ֥י אֶתְ/כֶ֛ם מִ/קִּבְרוֹתֵי/כֶ֖ם עַמִּ֑/י וְ/הֵבֵאתִ֥י אֶתְ/כֶ֖ם אֶל אַדְמַ֥ת יִשְׂרָאֵֽל", "en": {"kjv": "Therefore prophesy and say unto them, Thus saith the Lord God; Behold, O my people, I will open your graves, and cause you to come up out of your graves, and bring you into the land of Israel.", "web": "Therefore prophesy, and tell them, Thus says the Lord Yahweh: Behold, I will open your graves, and cause you to come up out of your graves, my people; and I will bring you into the land of Israel.", "bsb": "Therefore prophesy and tell them that this is what the Lord GOD says: ‘O My people, I will open your graves and bring you up from them, and I will bring you back to the land of Israel.", "asv": "Therefore prophesy, and say unto them, Thus saith the Lord Jehovah: Behold, I will open your graves, and cause you to come up out of your graves, O my people; and I will bring you into the land of Israel.", "ylt": "Therefore, prophesy, and thou hast said unto them, thus said the Lord Jehovah: Lo, I am opening your graves, And have brought you up out of your graves, O My people, And brought you in unto the land of Israel.", "dra": "Therefore prophesy, and say to them: Thus saith the Lord God: Behold I will open your graves, and will bring you out of your sepulchres, O my people: and will bring you into the land of Israel.", "bbe": "For this cause be a prophet to them, and say, This is what the Lord has said: See, I am opening the resting-places of your dead, and I will make you come up out of your resting-places, O my people; and I will take you into the land of Israel.", "geneva": "Therefore prophecie, and say vnto them, Thus saith the Lord God, Beholde, my people, I will open your graues, and cause you to come vp out of your sepulchres, and bring you into the lande of Israel,", "wycliffe": "Therfor profesie thou, and thou schalt seie to hem, The Lord God seith these thingis, Lo! Y schal opene youre graues, and Y schal lede you out of youre sepulcris, my puple, and Y schal lede you in to youre lond Israel.", "rotherham": "Therefore prophesy and thou shalt say unto them Thus saith My Lord Yahweh, Lo I myself am going to open your graves And will cause you to come up out of your graves. O my people,— And will bring you upon the soil of Israel.", "darby": "Therefore prophesy and say unto them, Thus saith the Lord Jehovah: Behold, I will open your graves, and cause you to come up out of your graves, O my people, and bring you into the land of Israel.", "twenty": "", "jps": "Therefore prophesy, and say unto them: Thus saith the L-rd GOD: Behold, I will open your graves, and cause you to come up out of your graves, O My people; and I will bring you into the land of Israel.", "acv": "Therefore prophesy, and say to them, Thus says the lord Jehovah: Behold, I will open your graves, and cause you to come up out of your graves, O my people, and I will bring you into the land of Israel.", "anderson": "", "haweis": "", "noyes": "Therefore prophesy, and say to them, Thus saith the Lord Jehovah: Behold, I will open your graves, and cause you to come up out of your graves, O my people, and bring you into the land of Israel.", "webster": "Therefore prophesy and say to them, Thus saith the Lord GOD; Behold, O my people, I will open your graves, and cause you to come out of your graves, and bring you into the land of Israel.", "vulgate": "propterea vaticinare et dices ad eos haec dicit Dominus Deus ecce ego aperiam tumulos vestros et educam vos de sepulchris vestris populus meus et inducam vos in terram Israhel;", "brenton": "Therefore prophesy and say, Thus saith the Lord; Behold, I will open your tombs, and will bring you up out of your tombs, and will bring you into the land of Israel."}}, {"v": 13, "ref": "37:13", "o": "וִֽ/ידַעְתֶּ֖ם כִּֽי אֲנִ֣י יְהוָ֑ה בְּ/פִתְחִ֣/י אֶת קִבְרֽוֹתֵי/כֶ֗ם וּ/בְ/הַעֲלוֹתִ֥/י אֶתְ/כֶ֛ם מִ/קִּבְרוֹתֵי/כֶ֖ם עַמִּֽ/י", "en": {"kjv": "And ye shall know that I am the Lord, when I have opened your graves, O my people, and brought you up out of your graves,", "web": "You shall know that I am Yahweh, when I have opened your graves, and caused you to come up out of your graves, my people.", "bsb": "Then you, My people, will know that I am the LORD, when I open your graves and bring you up from them.", "asv": "And ye shall know that I am Jehovah, when I have opened your graves, and caused you to come up out of your graves, O my people.", "ylt": "And ye have known that I am Jehovah, In My opening your graves, And in My bringing you up out of your graves, O My people.", "dra": "And you shall know that I am the Lord, when I shall have opened your sepulchres, and shall have brought you out of your graves, O my people:", "bbe": "And you will be certain that I am the Lord by my opening the resting-places of your dead and making you come up out of your resting-places, O my people.", "geneva": "And yee shall knowe that I am the Lord, when I haue opened your graues, O my people, and brought you vp out of your sepulchres,", "wycliffe": "And ye schulen wite, that Y am the Lord, whanne Y schal opene youre sepulcris, and schal lede you out of youre biriels, my puple;", "rotherham": "So shall ye know that I, am Yahweh,— When I open your graves. And cause you to come up out of your graves O my people,", "darby": "And ye shall know that I [am] Jehovah, when I have opened your graves, and have caused you to come up out of your graves, O my people.", "twenty": "", "jps": "And ye shall know that I am HaShem, when I have opened your graves, and caused you to come up out of your graves, O My people.", "acv": "And ye shall know that I am Jehovah when I have opened your graves, and caused you to come up out of your graves, O my people.", "anderson": "", "haweis": "", "noyes": "And ye shall know that I am Jehovah, when I open your graves, and cause you to come up out of your graves, O my people,", "webster": "And ye shall know that I [am] the LORD, when I have opened your graves, O my people, and brought you out of your graves,", "vulgate": "et scietis quia ego Dominus cum aperuero sepulchra vestra et eduxero vos de tumulis vestris populus meus;", "brenton": "And ye shall know that I am the Lord, when I have opened your graves, that I may bring up my people from their graves."}}, {"v": 14, "ref": "37:14", "o": "וְ/נָתַתִּ֨י רוּחִ֤/י בָ/כֶם֙ וִ/חְיִיתֶ֔ם וְ/הִנַּחְתִּ֥י אֶתְ/כֶ֖ם עַל אַדְמַתְ/כֶ֑ם וִ/ידַעְתֶּ֞ם כִּי אֲנִ֧י יְהוָ֛ה דִּבַּ֥רְתִּי וְ/עָשִׂ֖יתִי נְאֻם יְהוָֽה", "en": {"kjv": "And shall put my spirit in you, and ye shall live, and I shall place you in your own land: then shall ye know that I the Lord have spoken it, and performed it, saith the Lord.", "web": "I will put my Spirit in you, and you shall live, and I will place you in your own land: and you shall know that I, Yahweh, have spoken it and performed it, says Yahweh.", "bsb": "I will put My Spirit in you and you will live, and I will settle you in your own land. Then you will know that I, the LORD, have spoken, and I will do it, declares the LORD.’”", "asv": "And I will put my Spirit in you, and ye shall live, and I will place you in your own land: and ye shall know that I, Jehovah, have spoken it and performed it, saith Jehovah.", "ylt": "And I have given My Spirit in you, and ye have lived, And I have caused you to rest on your land, And ye have known that I Jehovah, I have spoken, and I have done it , An affirmation of Jehovah.'", "dra": "And shall have put my spirit in you, and you shall live, and I shall make you rest upon your own land: and you shall know that I the Lord have spoken, and done it, saith the Lord God:", "bbe": "And I will put my spirit in you, so that you may come to life, and I will give you a rest in your land: and you will be certain that I the Lord have said it and have done it, says the Lord.", "geneva": "And shall put my Spirit in you, and ye shall liue, and I shall place you in your owne land: then yee shall knowe that I the Lord haue spoken it, and performed it, sayth the Lord.", "wycliffe": "and Y schal yyue my spirit in you, and ye schulen lyue. And Y schal make you for to reste on youre lond; and ye schulen wite, that Y the Lord spak, and dide, seith the Lord God.", "rotherham": "And I will put my spirit within you and ye shall live, And I will settle you upon your own soil, So shall ye know that I, Yahweh have spoken and have performed. Declareth Yahweh.", "darby": "And I will put my Spirit in you, and ye shall live, and I will place you in your own land: and ye shall know that I Jehovah have spoken, and have done [it], saith Jehovah.", "twenty": "", "jps": "And I will put My spirit in you, and ye shall live, and I will place you in your own land; and ye shall know that I HaShem have spoken, and performed it, saith HaShem.'", "acv": "And I will put my Spirit in you, and ye shall live. And I will place you in your own land. And ye shall know that I, Jehovah, have spoken it and performed it, says Jehovah.", "anderson": "", "haweis": "", "noyes": "and put my breath within you, and ye live, and I place you in your own land; then shall ye know that I, Jehovah, have spoken it, and done it, saith Jehovah.", "webster": "And shall put my spirit in you, and ye shall live, and I shall place you in your own land: then shall ye know that I the LORD have spoken [it], and performed [it], saith the LORD.", "vulgate": "et dedero spiritum meum in vobis et vixeritis et requiescere vos faciam super humum vestram et scietis quia ego Dominus locutus sum et feci ait Dominus Deus;", "brenton": "And I will put my Spirit within you, and ye shall live, and I will place you upon your own land: and ye shall know that I am the Lord; I have spoken, and will do it, saith the Lord."}}, {"v": 15, "ref": "37:15", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "The word of the Lord came again unto me, saying,", "web": "Yahweh’s word came again to me, saying,", "bsb": "Again the word of the LORD came to me, saying,", "asv": "The word of Jehovah came again unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying,", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "The word of the Lord came againe vnto me, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "The word of Jehovah came again to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "The word of the LORD came again to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 16, "ref": "37:16", "o": "וְ/אַתָּ֣ה בֶן אָדָ֗ם קַח לְ/ךָ֙ עֵ֣ץ אֶחָ֔ד וּ/כְתֹ֤ב עָלָי/ו֙ לִֽ/יהוּדָ֔ה וְ/לִ/בְנֵ֥י יִשְׂרָאֵ֖ל חבר/ו חֲבֵרָ֑י/ו וּ/לְקַח֙ עֵ֣ץ אֶחָ֔ד וּ/כְת֣וֹב עָלָ֗י/ו לְ/יוֹסֵף֙ עֵ֣ץ אֶפְרַ֔יִם וְ/כָל בֵּ֥ית יִשְׂרָאֵ֖ל חבר/ו חֲבֵרָֽי/ו", "en": {"kjv": "Moreover, thou son of man, take thee one stick, and write upon it, For Judah, and for the children of Israel his companions: then take another stick, and write upon it, For Joseph, the stick of Ephraim, and for all the house of Israel his companions:", "web": "You, son of man, take one stick, and write on it, For Judah, and for the children of Israel his companions: then take another stick, and write on it, For Joseph, the stick of Ephraim, and for all the house of Israel his companions:", "bsb": "“And you, son of man, take a single stick and write on it: ‘Belonging to Judah and to the Israelites associated with him.’ Then take another stick and write on it: ‘Belonging to Joseph—the stick of Ephraim—and to all the house of Israel associated with him.’", "asv": "And thou, son of man, take thee one stick, and write upon it, For Judah, and for the children of Israel his companions: then take another stick, and write upon it, For Joseph, the stick of Ephraim, and for all the house of Israel his companions:", "ylt": "`And thou, son of man, take to thee one stick, and write on it, For Judah, and for the sons of Israel, his companions; and take another stick, and write on it, For Joseph, the stick of Ephraim, and all the house of Israel, his companions,", "dra": "And thou son of man, take thee a stick: and write upon it: Of Juda, and of the children of Israel his associates: and take another stick and write upon it: For Joseph the stick of Ephraim, and for all the house of Israel, and of his associates.", "bbe": "And you, son of man, take one stick, writing on it, For Judah and for the children of Israel who are in his company: then take another stick, writing on it, For Joseph, the stick of Ephraim, and all the children of Israel who are in his company:", "geneva": "Moreouer thou sonne of man, take thee a piece of wood, and write vpon it, Vnto Iudah, and to the children of Israel his companions the take another piece of wood, and write vpon it, Vnto Ioseph the tree of Ephraim, and to al the house of Israel his companions.", "wycliffe": "and he seide, And thou, sone of man, take to thee o tree, and write thou on it, To Juda, and to the sones of Israel, and to hise felowis. And take thou an other tree, and write on it, Joseph, the tree of Effraym, and of al the hous of Israel, and of hise felowis.", "rotherham": "Thou therefore Son of man Take thee one stick, and write upon it For Judah, and for the sons of Israel his companions, Then take thou another stick, and write upon it For Joseph the stick of Ephraim, and all the house of Israel his companions.", "darby": "And thou, son of man, take thee one stick, and write upon it, For Judah, and for the children of Israel, his companions. And take another stick, and write upon it, For Joseph, the stick of Ephraim and all the house of Israel, his companions.", "twenty": "", "jps": "'And thou, son of man, take thee one stick, and write upon it: For Judah, and for the children of Israel his companions; then take another stick, and write upon it: For Joseph, the stick of Ephraim, and of all the house of Israel his companions;", "acv": "And thou, son of man, take thee one stick, and write upon it, For Judah, and for the sons of Israel his companions. Then take another stick, and write upon it, For Joseph, the stick of Ephraim, and for all the house of Israel his companions.", "anderson": "", "haweis": "", "noyes": "Son of man, take thee one stick, and write upon it, \"For Judah, and for the sons of Israel, his companions\"; and take another stick, and write upon it, \"For Joseph, the stick of Ephraim, and the whole house of Israel, his companions.\"", "webster": "Moreover, thou son of man, take thee one stick, and write upon it, For Judah, and for the children of Israel his companions: then take another stick, and write upon it, For Joseph, the stick of Ephraim, and [for] all the house of Israel his companions:", "vulgate": "et tu fili hominis sume tibi lignum unum et scribe super illud Iudae et filiorum Israhel sociis eius et tolle lignum alterum et scribe super eum Ioseph lignum Ephraim et cunctae domui Israhel sociorumque eius;", "brenton": "Son of man, take for thyself a rod, and write upon it, Juda, and the children of Israel his adherents; and thou shalt take for thyself another rod, and thou shalt inscribe it for Joseph, the rod of Ephraim, and all the children of Israel that belong to him."}}, {"v": 17, "ref": "37:17", "o": "וְ/קָרַ֨ב אֹתָ֜/ם אֶחָ֧ד אֶל אֶחָ֛ד לְ/ךָ֖ לְ/עֵ֣ץ אֶחָ֑ד וְ/הָי֥וּ לַ/אֲחָדִ֖ים בְּ/יָדֶֽ/ךָ", "en": {"kjv": "And join them one to another into one stick; and they shall become one in thine hand.", "web": "and join them for you one to another into one stick, that they may become one in your hand.", "bsb": "Then join them together into one stick, so that they become one in your hand.", "asv": "and join them for thee one to another into one stick, that they may become one in thy hand.", "ylt": "and bring them near one unto another, to thee, for one stick, and they have become one in thy hand.", "dra": "And join them one to the other into one stick, and they shall become one in thy hand.", "bbe": "Then, joining them one to another, make them one stick, so that they may be one in your hand.", "geneva": "And thou shalt ioyne the one to another into one tree, and they shalbe as one in thine hand.", "wycliffe": "And ioyne thou tho trees oon to the tother in to o tree to thee; and tho schulen be in to onement in thin hond.", "rotherham": "Then bring them near—the one to the other —for thee into one stick,- And they shall become united in thy hand.", "darby": "And join them one to another into one stick; and they shall become one in thy hand.", "twenty": "", "jps": "and join them for thee one to another into one stick, that they may become one in thy hand.", "acv": "And join them one to another into one stick for thyself, that they may become one in thy hand.", "anderson": "", "haweis": "", "noyes": "Then join them one to another into one stick, that they may become one in thy hand.", "webster": "And join them one to another into one stick; and they shall become one in thy hand.", "vulgate": "et adiunge illa unum ad alterum tibi in lignum unum et erunt in unionem in manu tua;", "brenton": "And thou shalt joint them together for thyself, so as that they should bind themselves into one stick; and they shall be in thine hand."}}, {"v": 18, "ref": "37:18", "o": "וְ/כַֽ/אֲשֶׁר֙ יֹאמְר֣וּ אֵלֶ֔י/ךָ בְּנֵ֥י עַמְּ/ךָ֖ לֵ/אמֹ֑ר הֲ/לֽוֹא תַגִּ֥יד לָ֖/נוּ מָה אֵ֥לֶּה לָּֽ/ךְ", "en": {"kjv": "And when the children of thy people shall speak unto thee, saying, Wilt thou not shew us what thou meanest by these?", "web": "When the children of your people shall speak to you, saying, Will you not show us what you mean by these?", "bsb": "When your people ask you, ‘Won’t you explain to us what you mean by these?’", "asv": "And when the children of thy people shall speak unto thee, saying, Wilt thou not show us what thou meanest by these?", "ylt": "`And when sons of thy people speak unto thee, saying, Dost thou not declare to us what these are to thee?", "dra": "And when the children of thy people shall speak to thee, saying: Wilt thou not tell us what thou meanest by this?", "bbe": "And when the children of your people say to you, Will you not make clear to us what these things have to do with us?", "geneva": "And when the children of thy people shall speake vnto thee, saying, Wilt thou not shewe vs what thou meanest by these?", "wycliffe": "Sotheli whanne the sones of thi puple that speken, schulen seie to thee, Whether thou schewist not to vs, what thou wolt to thee in these thingis?", "rotherham": "And when the sons of thy people speak unto thee, saying,- Wilt thou not tell us what these things are to thee?", "darby": "And when the children of my people speak unto thee, saying, Wilt thou not declare unto us what thou meanest by these?", "twenty": "", "jps": "And when the children of thy people shall speak unto thee, saying: Wilt thou not tell us what thou meanest by these?", "acv": "And when the sons of thy people shall speak to thee, saying, Will thou not show us what thou mean by these?", "anderson": "", "haweis": "", "noyes": "And when the sons of thy people say to thee. \"Wilt thou not show us what thou meanest by these?\"", "webster": "And when the children of thy people shall speak to thee, saying, Wilt thou not show us what thou [meanest] by these?", "vulgate": "cum autem dixerint ad te filii populi tui loquentes nonne indicas nobis quid in his tibi velis;", "brenton": "And it shall come to pass, when the children of thy people shall say to thee, Wilt thou not tell us what thou meanest by these things?"}}, {"v": 19, "ref": "37:19", "o": "דַּבֵּ֣ר אֲלֵ/הֶ֗ם כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִנֵּה֩ אֲנִ֨י לֹקֵ֜חַ אֶת עֵ֤ץ יוֹסֵף֙ אֲשֶׁ֣ר בְּ/יַד אֶפְרַ֔יִם וְ/שִׁבְטֵ֥י יִשְׂרָאֵ֖ל חבר/ו חֲבֵרָ֑י/ו וְ/נָתַתִּי֩ אוֹתָ֨/ם עָלָ֜י/ו אֶת עֵ֣ץ יְהוּדָ֗ה וַֽ/עֲשִׂיתִ/ם֙ לְ/עֵ֣ץ אֶחָ֔ד וְ/הָי֥וּ אֶחָ֖ד בְּ/יָדִֽ/י", "en": {"kjv": "Say unto them, Thus saith the Lord God; Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his fellows, and will put them with him, even with the stick of Judah, and make them one stick, and they shall be one in mine hand.", "web": "tell them, Thus says the Lord Yahweh: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his companions; and I will put them with it, with the stick of Judah, and make them one stick, and they shall be one in my hand.", "bsb": "you are to tell them that this is what the Lord GOD says: ‘I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel associated with him, and I will put them together with the stick of Judah. I will make them into a single stick, and they will become one in My hand.’", "asv": "say unto them, Thus saith the Lord Jehovah: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his companions; and I will put them with it, even with the stick of Judah, and make them one stick, and they shall be one in my hand.", "ylt": "Speak unto them, Thus said the Lord Jehovah: Lo, I am taking the stick of Joseph, that is in the hand of Ephraim, and the tribes of Israel his companions, and have given them unto him, with the stick of Judah, and have made them become one stick, and they have been one in My hand.", "dra": "Say to them: Thus saith the Lord God: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel that are associated with him, and I will put them together with the stick of Juda, and will make them one stick: and they shall be one in his hand.", "bbe": "Then say to them, This is what the Lord has said: See, I am taking the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel who are in his company; and I will put it on the stick of Judah and make them one stick, and they will be one in my hand.", "geneva": "Thou shalt answere them, Thus sayeth the Lord God, Behold, I wil take the tree of Ioseph, which is in the hande of Ephraim, and the tribes of Israel his fellowes, and will put them with him, euen with the tree of Iudah, and make them one tree, and they shalbe one in mine hand.", "wycliffe": "thou schalt speke to hem, The Lord God seith these thingis, Lo! Y schal take the tree of Joseph, which is in the hond of Effraym, and the lynagis of Israel, that ben ioyned to hym, and Y schal yyue hem togidere with the tree of Juda; and Y schal make hem in to o tree, and thei schulen be oon in the hond of hym.", "rotherham": "speak unto them Thus saith My Lord Yahweh, Lo! I, myself, am going to take the stick of Joseph. which is in the hand of Ephraim, and the tribes of Israel, his companions,— And I will place them upon it even upon the stick of Judah. And will make of them one stick, And they shall become one in my hand.", "darby": "say unto them, Thus saith the Lord Jehovah: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his companions, and will put them with this, with the stick of Judah, and make them one stick, and they shall be one in my hand.", "twenty": "", "jps": "say into them: Thus saith the L-rd GOD: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his companions; and I will put them unto him together with the stick of Judah, and make them one stick, and they shall be one in My hand.", "acv": "say to them, Thus says the lord Jehovah: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his companions, and I will put them with it, even with the stick of Judah, and make them one stick, and they shall be one in my hand.", "anderson": "", "haweis": "", "noyes": "say to them, Thus saith the Lord Jehovah: Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and of the tribes of Israel, his companions, and will unite them and him with the stick of Judah, and make them one stick, and they shall be one in my hand.", "webster": "Say to them, Thus saith the Lord GOD; Behold, I will take the stick of Joseph, which [is] in the hand of Ephraim, and the tribes of Israel his fellows, and will put them with him, [even] with the stick of Judah, and make them one stick, and they shall be one in my hand.", "vulgate": "loqueris ad eos haec dicit Dominus Deus ecce ego adsumam lignum Ioseph quod est in manu Ephraim et tribus Israhel quae iunctae sunt ei et dabo eas pariter cum ligno Iuda et faciam eas in lignum unum et erunt unum in manu eius;", "brenton": "Then shalt thou say to them, Thus saith the Lord; behold, I will take the tribe of Joseph, which is in the hand of Ephraim, and the tribes of Israel that belong to him, and I will add them to the tribe of Juda, and they shall become one rod in the hand of Juda."}}, {"v": 20, "ref": "37:20", "o": "וְ/הָי֨וּ הָ/עֵצִ֜ים אֲֽשֶׁר תִּכְתֹּ֧ב עֲלֵי/הֶ֛ם בְּ/יָדְ/ךָ֖ לְ/עֵינֵי/הֶֽם", "en": {"kjv": "And the sticks whereon thou writest shall be in thine hand before their eyes.", "web": "The sticks whereon you write shall be in your hand before their eyes.", "bsb": "When the sticks on which you write are in your hand and in full view of the people,", "asv": "And the sticks whereon thou writest shall be in thy hand before their eyes.", "ylt": "And the sticks on which thou writest have been in thy hand before thine eyes,", "dra": "And the sticks whereon thou hast written, shall be in thy hand, before their eyes.", "bbe": "And the sticks with your writing on them will be in your hand before their eyes.", "geneva": "And the pieces of wood, whereon thou writest, shalbe in thine hand, in their sight.", "wycliffe": "Sotheli the trees, on whiche thou hast write, schulen be in thin hond bifore the iyen of hem.", "rotherham": "And the sticks whereon thou shalt write shall remain in thy hand before their eyes.", "darby": "And the sticks whereon thou writest shall be in thy hand before their eyes.", "twenty": "", "jps": "And the sticks whereon thou writest shall be in thy hand before their eyes.", "acv": "And the sticks on which thou write shall be in thy hand before their eyes.", "anderson": "", "haweis": "", "noyes": "And let the sticks whereon thou writest be in thy hand before their eyes;", "webster": "And the sticks on which thou writest shall be in thy hand before their eyes.", "vulgate": "erunt autem ligna super quae scripseris in manu tua in oculis eorum;", "brenton": "And the rods on which thou didst write shall be in thine hand in their presence."}}, {"v": 21, "ref": "37:21", "o": "וְ/דַבֵּ֣ר אֲלֵי/הֶ֗ם כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ הִנֵּ֨ה אֲנִ֤י לֹקֵ֨חַ֙ אֶת בְּנֵ֣י יִשְׂרָאֵ֔ל מִ/בֵּ֥ין הַ/גּוֹיִ֖ם אֲשֶׁ֣ר הָֽלְכוּ שָׁ֑ם וְ/קִבַּצְתִּ֤י אֹתָ/ם֙ מִ/סָּבִ֔יב וְ/הֵבֵאתִ֥י אוֹתָ֖/ם אֶל אַדְמָתָֽ/ם", "en": {"kjv": "And say unto them, Thus saith the Lord God; Behold, I will take the children of Israel from among the heathen, whither they be gone, and will gather them on every side, and bring them into their own land:", "web": "Say to them, Thus says the Lord Yahweh: Behold, I will take the children of Israel from among the nations, where they are gone, and will gather them on every side, and bring them into their own land:", "bsb": "you are to tell them that this is what the Lord GOD says: ‘I will take the Israelites out of the nations to which they have gone, and I will gather them from all around and bring them into their own land.", "asv": "And say unto them, Thus saith the Lord Jehovah: Behold, I will take the children of Israel from among the nations, whither they are gone, and will gather them on every side, and bring them into their own land:", "ylt": "and speak thou unto them: Thus said the Lord Jehovah: Lo, I am taking the sons of Israel, From among the nations whither they have gone, And have gathered them from round about, And I have brought them in unto their land.", "dra": "And thou shalt say to them: Thus saith the Lord God: Behold, I will take of the children of Israel from the midst of the nations whither they are gone: and I will gather them on every side, and will bring them to their own land.", "bbe": "And say to them, These are the words of the Lord: See, I am taking the children of Israel from among the nations where they have gone, and will get them together on every side, and take them into their land:", "geneva": "And say vnto them, Thus saith the Lord God, Beholde, I will take the children of Israel from among the heathen, whither they be gone, and wil gather them on euery side, and bring them into their owne land.", "wycliffe": "And thou schalt seie to hem, The Lord God seith these thingis, Lo! Y schal take the sones of Israel fro the myddis of naciouns, to whiche thei yeden forth; and Y schal gadere hem togidere on ech side. And Y schal brynge hem to her lond,", "rotherham": "Therefore speak thou unto them Thus, saith My Lord Yahweh, Lo! I myself, am going to take the sons of Israel, from among the nations whither they have gone,— And I will gather them from every side, And will bring them in upon their own soil;", "darby": "And say unto them, Thus saith the Lord Jehovah: Behold, I will take the children of Israel from among the nations, whither they are gone, and will gather them from every side, and bring them into their own land:", "twenty": "", "jps": "And say unto them: Thus saith the L-rd GOD: Behold, I will take the children of Israel from among the nations, whither they are gone, and will gather them on every side, and bring them into their own land;", "acv": "And say to them, Thus says the lord Jehovah: Behold, I will take the sons of Israel from among the nations where they have gone, and will gather them on every side, and bring them into their own land.", "anderson": "", "haweis": "", "noyes": "and say thou to them, Thus saith the Lord Jehovah: Behold, I will take the sons of Israel from among the nations whither they are gone, and will gather them from every side, and bring them into their own land.", "webster": "And say to them, Thus saith the Lord GOD; Behold, I will take the children of Israel from among the heathen, whither they are gone, and will gather them on every side, and bring them into their own land:", "vulgate": "et dices ad eos haec dicit Dominus Deus ecce ego adsumam filios Israhel de medio nationum ad quas abierunt et congregabo eos undique et adducam eos ad humum suam;", "brenton": "And thou shalt say to them, Thus saith the Lord God; Behold, I will take the whole house of Israel out of the midst of the nations, among whom they have gone, and I will gather them from all that are round about them, and I will bring them into the land of Israel."}}, {"v": 22, "ref": "37:22", "o": "וְ/עָשִׂ֣יתִי אֹ֠תָ/ם לְ/ג֨וֹי אֶחָ֤ד בָּ/אָ֨רֶץ֙ בְּ/הָרֵ֣י יִשְׂרָאֵ֔ל וּ/מֶ֧לֶךְ אֶחָ֛ד יִֽהְיֶ֥ה לְ/כֻלָּ֖/ם לְ/מֶ֑לֶךְ וְ/לֹ֤א יהיה יִֽהְיוּ עוֹד֙ לִ/שְׁנֵ֣י גוֹיִ֔ם וְ/לֹ֨א יֵחָ֥צוּ ע֛וֹד לִ/שְׁתֵּ֥י מַמְלָכ֖וֹת עֽוֹד", "en": {"kjv": "And I will make them one nation in the land upon the mountains of Israel; and one king shall be king to them all: and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all:", "web": "and I will make them one nation in the land, on the mountains of Israel; and one king shall be king to them all; and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all;", "bsb": "I will make them one nation in the land, on the mountains of Israel, and one king will rule over all of them. Then they will no longer be two nations and will never again be divided into two kingdoms.", "asv": "and I will make them one nation in the land, upon the mountains of Israel; and one king shall be king to them all; and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all;", "ylt": "And I have made them become one nation in the land, on mountains of Israel, And one king is to them all for king, And they are no more as two nations, Nor are they divided any more into two kingdoms again.", "dra": "And I will make them one nation in the land on the mountains of Israel, and one king shall be king over them all: and they shall no more be two nations, neither shall they be divided any more into two kingdoms.", "bbe": "And I will make them one nation in the land, on the mountains of Israel; and one king will be king over them all: and they will no longer be two nations, and will no longer be parted into two kingdoms:", "geneva": "And I will make them one people in the lande, vpon the mountaines of Israel, and one king shalbe king to them all: and they shalbe no more two peoples, neither bee deuided any more henceforth into two kingdomes.", "wycliffe": "and Y schal make hem o folc in the lond, in the hillis of Israel, and o kyng schal be comaundynge to alle: and thei schulen no more be twei folkis, and thei schulen no more be departid in to twey rewmes.", "rotherham": "And will make of them one nation in the land. among the mountains of Israel, And one king, shall they all have for king, —And they shall remain no longer two nations, Nor shall they be divided into two kingdoms any more.", "darby": "and I will make them one nation in the land upon the mountains of Israel; and one king shall be king to them all: and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all.", "twenty": "", "jps": "and I will make them one nation in the land, upon the mountains of Israel, and one king shall be king to them all; and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all;", "acv": "And I will make them one nation in the land, upon the mountains of Israel, and one king shall be king to them all. And they shall no more be two nations, nor shall they be divided into two kingdoms any more at all.", "anderson": "", "haweis": "", "noyes": "And I will make them one nation in the land, upon the mountains of Israel; and one king shall be king over them all; and they shall no more be two nations, and no more shall they be divided into two kingdoms.", "webster": "And I will make them one nation in the land upon the mountains of Israel; and one king shall be king to them all: and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all:", "vulgate": "et faciam eos gentem unam in terra in montibus Israhel et rex unus erit omnibus imperans et non erunt ultra duae gentes nec dividentur amplius in duo regna;", "brenton": "And I will make them a nation in my land, even on the mountains of Israel; and they shall have one prince: and they shall be no more two nations, neither shall they be divided any more at all into two kingdoms:"}}, {"v": 23, "ref": "37:23", "o": "וְ/לֹ֧א יִֽטַמְּא֣וּ ע֗וֹד בְּ/גִלּֽוּלֵי/הֶם֙ וּ/בְ/שִׁקּ֣וּצֵי/הֶ֔ם וּ/בְ/כֹ֖ל פִּשְׁעֵי/הֶ֑ם וְ/הוֹשַׁעְתִּ֣י אֹתָ֗/ם מִ/כֹּ֤ל מוֹשְׁבֹֽתֵי/הֶם֙ אֲשֶׁ֣ר חָטְא֣וּ בָ/הֶ֔ם וְ/טִהַרְתִּ֤י אוֹתָ/ם֙ וְ/הָיוּ לִ֣/י לְ/עָ֔ם וַ/אֲנִ֕י אֶהְיֶ֥ה לָ/הֶ֖ם לֵ/אלֹהִֽים", "en": {"kjv": "Neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions: but I will save them out of all their dwellingplaces, wherein they have sinned, and will cleanse them: so shall they be my people, and I will be their God.", "web": "neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions; but I will save them out of all their dwelling places, in which they have sinned, and will cleanse them: so shall they be my people, and I will be their God.", "bsb": "They will no longer defile themselves with their idols or detestable images, or with any of their transgressions. I will save them from all their apostasies by which they sinned, and I will cleanse them. Then they will be My people, and I will be their God.", "asv": "neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions; but I will save them out of all their dwelling-places, wherein they have sinned, and will cleanse them: so shall they be my people, and I will be their God.", "ylt": "Nor are they defiled any more with their idols, And with their abominations, And with any of their transgressions, And I have saved them out of all their dwellings, In which they have sinned, And I have cleansed them, And they have been to Me for a people, And I--I am to them for God.", "dra": "Nor shall they be defiled any more with their idols, nor with their abominations, nor with all their iniquities: and I will save them out of all the places in which they have sinned, and I will cleanse them: and they shall be my people, and I will be their God.", "bbe": "And they will no longer make themselves unclean with their images or with their hated things or with any of their sins: but I will give them salvation from all their turning away in which they have done evil, and will make them clean; and they will be to me a people, and I will be to them a God.", "geneva": "Neither shall they bee polluted any more with their idoles, nor with their abominations, nor with any of their transgressions: but I will saue them out of all their dwelling places, wherein they haue sinned, and will clense them: so shall they be my people, and I will be their God.", "wycliffe": "And thei schulen no more be defoulid in her idols, and her abhomynaciouns, and in alle her wickidnessis. And Y schal make hem saaf fro alle her seetis, in which thei synneden, and Y schal clense hem; and thei schulen be a puple to me, and Y schal be God to hem.", "rotherham": "Neither shall they defile themselves any more With their manufactured gods or With their detestable things, or With any of their transgressions,- But I will save them out of all their dwelling- places, wherein they have sinned, And I will cleanse them And they shall become my people, And I, will become their God.", "darby": "And they shall not defile themselves any more with their idols, or with their detestable things, or with any of their transgressions; and I will save them out of all their dwelling-places wherein they have sinned, and will cleanse them; and they shall be my people, and I will be theirGod.", "twenty": "", "jps": "neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions; but I will save them out of all their dwelling-places, wherein they have sinned, and will cleanse them; so shall they be My people, and I will be their G-d.", "acv": "Neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions, but I will save them out of all their dwelling-places in which they have sinned, and will cleanse them. So they shall be my people, and I will be their God.", "anderson": "", "haweis": "", "noyes": "Neither shall they defile themselves any more with their idols, nor with their abominations, nor with any of their transgressions; but I will save them from all their dwelling-places wherein they have sinned, and will cleanse them; and they shall be my people, and I will be their God.", "webster": "Neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions: but I will save them out of all their dwelling-places, in which they have sinned, and will cleanse them: so shall they be my people, and I will be their God.", "vulgate": "neque polluentur ultra in idolis suis et abominationibus suis et in cunctis iniquitatibus suis et salvos eos faciam de universis sedibus suis in quibus peccaverunt et mundabo eos et erunt mihi populus et ego ero eis Deus;", "brenton": "that they may no more defile themselves with their idols; and I will deliver them from all their transgressions whereby they have sinned, and will cleanse them; and they shall be to me a people, and I the Lord will be to them a God."}}, {"v": 24, "ref": "37:24", "o": "וְ/עַבְדִּ֤/י דָוִד֙ מֶ֣לֶךְ עֲלֵי/הֶ֔ם וְ/רוֹעֶ֥ה אֶחָ֖ד יִהְיֶ֣ה לְ/כֻלָּ֑/ם וּ/בְ/מִשְׁפָּטַ֣/י יֵלֵ֔כוּ וְ/חֻקֹּתַ֥/י יִשְׁמְר֖וּ וְ/עָשׂ֥וּ אוֹתָֽ/ם", "en": {"kjv": "And David my servant shall be king over them; and they all shall have one shepherd: they shall also walk in my judgments, and observe my statutes, and do them.", "web": "My servant David shall be king over them; and they all shall have one shepherd: they shall also walk in my ordinances, and observe my statutes, and do them.", "bsb": "My servant David will be king over them, and there will be one shepherd for all of them. They will follow My ordinances and keep and observe My statutes.", "asv": "And my servant David shall be king over them; and they all shall have one shepherd: they shall also walk in mine ordinances, and observe my statutes, and do them.", "ylt": "And My servant David is king over them, And one shepherd have they all, And in My judgments they go, And My statutes they keep, and have done them.", "dra": "And my servant David shall be king over them, and they shall have one shepherd: they shall walk in my judgments, and shall keep my commandments, and shall do them.", "bbe": "And my servant David will be king over them; and they will all have one keeper: and they will be guided by my orders and will keep my rules and do them.", "geneva": "And Dauid my seruant shalbe king ouer them, and they all shall haue one shepheard: they shall also walke in my iudgements, and obserue my statutes, and doe them.", "wycliffe": "And my seruaunt Dauid schal be kyng on hem, and o scheepherde schal be of alle hem; thei schulen go in my domes, and thei schulen kepe my comaundementis, and schulen do tho.", "rotherham": "And my servant David shall be king over them, And one shepherd, shall they all have, And in my regulations, shall they walk, And my statutes, shall they observe and do them.", "darby": "And David my servant shall be king over them; and they all shall have one shepherd: and they shall walk in mine ordinances, and keep my statutes, and do them.", "twenty": "", "jps": "And My servant David shall be king over them, and they all shall have one shepherd; they shall also walk in Mine ordinances, and observe My statutes, and do them.", "acv": "And my servant David shall be king over them, and they all shall have one shepherd. They shall also walk in my ordinances, and observe my statutes, and do them.", "anderson": "", "haweis": "", "noyes": "And my servant David shall be king over them, and they shall have one shepherd; and they shall walk in my commandments, and observe my statutes, and do them.", "webster": "And David my servant [shall be] king over them; and they all shall have one shepherd: they shall also walk in my judgments, and observe my statutes, and do them.", "vulgate": "et servus meus David rex super eos et pastor unus erit omnium eorum in iudiciis meis ambulabunt et mandata mea custodient et facient ea;", "brenton": "And my servant David shall be a prince in the midst of them: there shall be one shepherd of them all; for they shall walk in mine ordinances, and keep my judgments, and do them."}}, {"v": 25, "ref": "37:25", "o": "וְ/יָשְׁב֣וּ עַל הָ/אָ֗רֶץ אֲשֶׁ֤ר נָתַ֨תִּי֙ לְ/עַבְדִּ֣/י לְ/יַֽעֲקֹ֔ב אֲשֶׁ֥ר יָֽשְׁבוּ בָ֖/הּ אֲבֽוֹתֵי/כֶ֑ם וְ/יָשְׁב֣וּ עָלֶ֡י/הָ הֵ֠מָּה וּ/בְנֵי/הֶ֞ם וּ/בְנֵ֤י בְנֵי/הֶם֙ עַד עוֹלָ֔ם וְ/דָוִ֣ד עַבְדִּ֔/י נָשִׂ֥יא לָ/הֶ֖ם לְ/עוֹלָֽם", "en": {"kjv": "And they shall dwell in the land that I have given unto Jacob my servant, wherein your fathers have dwelt; and they shall dwell therein, even they, and their children, and their children’s children for ever: and my servant David shall be their prince for ever.", "web": "They shall dwell in the land that I have given to Jacob my servant, in which your fathers lived; and they shall dwell therein, they, and their children, and their children’s children, forever: and David my servant shall be their prince for ever.", "bsb": "They will live in the land that I gave to My servant Jacob, where your fathers lived. They will live there forever with their children and grandchildren, and My servant David will be their prince forever.", "asv": "And they shall dwell in the land that I have given unto Jacob my servant, wherein your fathers dwelt; and they shall dwell therein, they, and their children, and their children’s children, for ever: and David my servant shall be their prince for ever.", "ylt": "And they have dwelt on the land that I gave to My servant, to Jacob, In which your fathers have dwelt, And they have dwelt on it, they and their sons, And their son's sons--unto the age, And David My servant is their prince--to the age.", "dra": "And they shall dwell in the land which I gave to my servant Jacob, wherein your fathers dwelt, and they shall dwell in it, they and their children, and their children's children, for ever: and David my servant shall be their prince for ever.", "bbe": "And they will be living in the land which I gave to Jacob, my servant, in which your fathers were living; and they will go on living there, they and their children and their children's children, for ever: and David, my servant, will be their ruler for ever.", "geneva": "And they shall dwell in the lande, that I haue giuen vnto Iaakob my seruant, where your fathers haue dwelt, and they shall dwel therein, euen they, and their sonnes, and their sonnes sonnes for euer, and my seruant Dauid shall bee their prince for euer.", "wycliffe": "And thei schulen dwelle on the lond, which Y yaf to my seruaunt Jacob, in which youre fadris dwelliden; and thei schulen dwelle on that lond, thei, and the sones of hem, and the sones of her sones, til in to with outen ende; and Dauid, my seruaunt, schal be the prince of hem with outen ende.", "rotherham": "And they shall dwell upon the land. which I gave to my servant- to Jacob, Wherein your fathers dwelt,— Yea they shall dwell thereupon. They, and their children and their children’s children Unto times age-abiding, And David my servant shall be prince unto them Unto times age-abiding.", "darby": "And they shall dwell in the land that I have given unto Jacob my servant, wherein your fathers have dwelt; and they shall dwell therein, they, and their children, and their children's children for ever: and David my servant shall be their prince for ever.", "twenty": "", "jps": "And they shall dwell in the land that I have given unto Jacob My servant, wherein your fathers dwelt; and they shall dwell therein, they, and their children, and their children's children, for ever; and David My servant shall be their prince for ever.", "acv": "And they shall dwell in the land that I have given to Jacob my servant, in which your fathers dwelt. And they shall dwell therein, they, and their sons, and their son's sons, forever. And David my servant shall be their ruler forever.", "anderson": "", "haweis": "", "noyes": "And they shall dwell in the land which I gave to my servant Jacob, wherein your fathers dwelt; they shall dwell therein, and their sons and their son’s sons forever; and David, my servant, shall be their prince forever.", "webster": "And they shall dwell in the land that I have given to Jacob my servant, in which your fathers have dwelt, and they shall dwell in it, [even] they, and their children, and their children's children for ever: and my servant David [shall be] their prince for ever.", "vulgate": "et habitabunt super terram quam dedi servo meo Iacob in qua habitaverunt patres vestri et habitabunt super eam ipsi et filii eorum et filii filiorum eorum usque in sempiternum et David servus meus princeps eorum in perpetuum;", "brenton": "And they shall dwell in their land, which I have given to my servant Jacob, where their fathers dwelt; and they shall dwell upon it: and David my servant shall be their prince forever."}}, {"v": 26, "ref": "37:26", "o": "וְ/כָרַתִּ֤י לָ/הֶם֙ בְּרִ֣ית שָׁל֔וֹם בְּרִ֥ית עוֹלָ֖ם יִהְיֶ֣ה אוֹתָ֑/ם וּ/נְתַתִּי/ם֙ וְ/הִרְבֵּיתִ֣י אוֹתָ֔/ם וְ/נָתַתִּ֧י אֶת מִקְדָּשִׁ֛/י בְּ/תוֹכָ֖/ם לְ/עוֹלָֽם", "en": {"kjv": "Moreover I will make a covenant of peace with them; it shall be an everlasting covenant with them: and I will place them, and multiply them, and will set my sanctuary in the midst of them for evermore.", "web": "Moreover I will make a covenant of peace with them; it shall be an everlasting covenant with them; and I will place them, and multiply them, and will set my sanctuary in their midst forever more.", "bsb": "And I will make a covenant of peace with them; it will be an everlasting covenant. I will establish them and multiply them, and I will set My sanctuary among them forever.", "asv": "Moreover I will make a covenant of peace with them; it shall be an everlasting covenant with them; and I will place them, and multiply them, and will set my sanctuary in the midst of them for evermore.", "ylt": "And I have made to them a covenant of peace, A covenant age-during it is with them, And I have placed them, and multiplied them, And placed My sanctuary in their midst--to the age.", "dra": "And I will make a covenant of peace with them, it shall be an everlasting covenant with them: and I will establish them, and will multiply them, and will set my sanctuary in the midst of them for ever.", "bbe": "And I will make an agreement of peace with them: it will be an eternal agreement with them: and I will have mercy on them and make their numbers great, and will put my holy place among them for ever.", "geneva": "Moreouer, I will make a couenant of peace with them: it shall be an euerlasting couenant with them, and I wil place them, and multiply them, and wil set my Sanctuarie among them for euermore.", "wycliffe": "And Y schal smyte to hem a boond of pees; it schal be a couenaunt euerlastynge to hem, and Y schal founde hem, and Y schal multiplie, and Y schal yyue myn halewing in the myddis of hem with outen ende.", "rotherham": "And I will solemnise to them a covenant of prosperity, A covenant age-abiding, shall it be with them,— And I will place them. And multiply them, And set my sanctuary in the midst of them. Unto times age-abiding.", "darby": "And I will make a covenant of peace with them: it shall be an everlasting covenant with them; and I will place them, and multiply them, and will set my sanctuary in the midst of them for ever.", "twenty": "", "jps": "Moreover I will make a covenant of peace with them--it shall be an everlasting covenant with them; and I will establish them, and multiply them, and will set My sanctuary in the midst of them for ever.", "acv": "Moreover I will make a covenant of peace with them. It shall be an everlasting covenant with them, and I will place them, and multiply them, and will set my sanctuary in the midst of them for evermore.", "anderson": "", "haweis": "", "noyes": "And I will make with them a covenant of peace; it shall be an everlasting covenant with them. And I will place them [in the land], and multiply them, and set my sanctuary in the midst of them forever.", "webster": "Moreover I will make a covenant of peace with them; it shall be an everlasting covenant with them: and I will place them, and multiply them, and will set my sanctuary in the midst of them for evermore.", "vulgate": "et percutiam illis foedus pacis pactum sempiternum erit eis et fundabo eos et multiplicabo et dabo sanctificationem meam in medio eorum in perpetuum;", "brenton": "And I will make with them a covenant of peace; it shall be an everlasting covenant with them; and I will establish my sanctuary in the midst of them for ever."}}, {"v": 27, "ref": "37:27", "o": "וְ/הָיָ֤ה מִשְׁכָּנִ/י֙ עֲלֵי/הֶ֔ם וְ/הָיִ֥יתִי לָ/הֶ֖ם לֵֽ/אלֹהִ֑ים וְ/הֵ֖מָּה יִֽהְיוּ לִ֥/י לְ/עָֽם", "en": {"kjv": "My tabernacle also shall be with them: yea, I will be their God, and they shall be my people.", "web": "My tent also shall be with them; and I will be their God, and they shall be my people.", "bsb": "My dwelling place will be with them; I will be their God, and they will be My people.", "asv": "My tabernacle also shall be with them; and I will be their God, and they shall be my people.", "ylt": "And My tabernacle hath been over them, And I have been to them for God, And they have been to Me for a people.", "dra": "And my tabernacle shall be with them: and I will be their God, and they shall be my people.", "bbe": "And my House will be over them; and I will be to them a God, and they will be to me a people.", "geneva": "My tabernacle also shalbe with them: yea, I will be their God, and they shalbe my people.", "wycliffe": "And my tabernacle schal be among hem, and Y schal be God to hem, and thei schulen be a puple to me.", "rotherham": "And my habitation shall be over them, And I will become their God,- And they, shall become my people,", "darby": "And my tabernacle shall be over them; and I will be theirGod, and they shall be my people.", "twenty": "", "jps": "My dwelling-place also shall be over them; and I will be their G-d, and they shall be My people.", "acv": "My tabernacle shall also be with them, and I will be their God, and they shall be my people.", "anderson": "", "haweis": "", "noyes": "And my dwelling-place shall be with them; yea, I will be their God, and they shall be my people;", "webster": "My tabernacle also shall be with them: and I will be their God, and they shall be my people.", "vulgate": "et erit tabernaculum meum in eis et ero eis Deus et ipsi erunt mihi populus;", "brenton": "And my tabernacle shall be among them; and I will be to them a God, and they shall be my people."}}, {"v": 28, "ref": "37:28", "o": "וְ/יָֽדְעוּ֙ הַ/גּוֹיִ֔ם כִּ֚י אֲנִ֣י יְהוָ֔ה מְקַדֵּ֖שׁ אֶת יִשְׂרָאֵ֑ל בִּ/הְי֧וֹת מִקְדָּשִׁ֛/י בְּ/תוֹכָ֖/ם לְ/עוֹלָֽם", "en": {"kjv": "And the heathen shall know that I the Lord do sanctify Israel, when my sanctuary shall be in the midst of them for evermore.", "web": "The nations shall know that I am Yahweh who sanctifies Israel, when my sanctuary shall be in their midst forever more.", "bsb": "Then the nations will know that I the LORD sanctify Israel, when My sanctuary is among them forever.’”", "asv": "And the nations shall know that I am Jehovah that sanctifieth Israel, when my sanctuary shall be in the midst of them for evermore.", "ylt": "And known have the nations that I Jehovah am sanctifying Israel, In My sanctuary being in their midst--to the age!'", "dra": "And the nations shall know that I am the Lord the sanctifier of Israel, when my sanctuary shall be in the midst of them for ever.", "bbe": "And the nations will be certain that I who make Israel holy am the Lord, when my holy place is among them for ever.", "geneva": "Thus the heathen shall knowe, that I the Lord do sanctifie Israel, when my Sanctuarie shall be among them for euermore.", "wycliffe": "And hethene men schulen wite, that Y am the Lord, halewere of Israel, whanne myn halewyng schal be in the myddis of hem with outen ende.", "rotherham": "So shall the nations know that I, Yahweh, am hallowing Israel,- When my sanctuary is in the midst of them Unto times age-abiding.", "darby": "And the nations shall know that I Jehovah do hallow Israel, when my sanctuary shall be in the midst of them for ever.", "twenty": "", "jps": "And the nations shall know that I am HaShem that sanctify Israel, when My sanctuary shall be in the midst of them for ever.'", "acv": "And the nations shall know that I am Jehovah, who sanctifies Israel, when my sanctuary shall be in the midst of them for evermore.", "anderson": "", "haweis": "", "noyes": "and the nations shall know that I, Jehovah, do sanctify Israel, when my sanctuary shall be in the midst of them forevermore.", "webster": "And the heathen shall know that I the LORD do sanctify Israel, when my sanctuary shall be in the midst of them for ever.", "vulgate": "et scient gentes quia ego Dominus sanctificator Israhel cum fuerit sanctificatio mea in medio eorum in perpetuum;", "brenton": "And the nations shall know that I am the Lord that sanctifies them, when my sanctuary is in the midst of them for ever."}}]}, {"c": 38, "verses": [{"v": 1, "ref": "38:1", "o": "וַ/יְהִ֥י דְבַר יְהוָ֖ה אֵלַ֥/י לֵ/אמֹֽר", "en": {"kjv": "And the word of the Lord came unto me, saying,", "web": "Yahweh’s word came to me, saying,", "bsb": "And the word of the LORD came to me, saying,", "asv": "And the word of Jehovah came unto me, saying,", "ylt": "And there is a word of Jehovah unto me, saying:", "dra": "And the word of the Lord came to me, saying:", "bbe": "And the word of the Lord came to me, saying,", "geneva": "And the worde of the Lord came vnto mee, saying,", "wycliffe": "And the word of the Lord was maad to me,", "rotherham": "And the word of Yahweh came unto me, saying:", "darby": "And the word of Jehovah came unto me, saying,", "twenty": "", "jps": "And the word of HaShem came unto me, saying:", "acv": "And the word of Jehovah came to me, saying,", "anderson": "", "haweis": "", "noyes": "And the word of Jehovah came to me, saying:", "webster": "And the word of the LORD came to me, saying,", "vulgate": "et factus est sermo Domini ad me dicens;", "brenton": "And the word of the Lord came to me, saying,"}}, {"v": 2, "ref": "38:2", "o": "בֶּן אָדָ֗ם שִׂ֤ים פָּנֶ֨י/ךָ֙ אֶל גּוֹג֙ אֶ֣רֶץ הַ/מָּג֔וֹג נְשִׂ֕יא רֹ֖אשׁ מֶ֣שֶׁךְ וְ/תֻבָ֑ל וְ/הִנָּבֵ֖א עָלָֽי/ו", "en": {"kjv": "Son of man, set thy face against Gog, the land of Magog, the chief prince of Meshech and Tubal, and prophesy against him,", "web": "Son of man, set your face toward Gog, of the land of Magog, the prince of Rosh, Meshech, and Tubal, and prophesy against him,", "bsb": "“Son of man, set your face against Gog of the land of Magog, the chief prince of Meshech and Tubal. Prophesy against him", "asv": "Son of man, set thy face toward Gog, of the land of Magog, the prince of Rosh, Meshech, and Tubal, and prophesy against him,", "ylt": "`Son of man, set thy face unto Gog, of the land of Magog, prince of Rosh, Meshech, and Tubal, and prophesy concerning him,", "dra": "Son of man, set thy face against Gog, the land of Magog, the chief prince of Mosoch and Thubal: and prophesy of him,", "bbe": "Son of man, let your face be turned against Gog, of the land of Magog, the ruler of Rosh, Meshech, and Tubal, and be a prophet against him,", "geneva": "Sonne of man, set thy face against Gog, and against the lande of Magog, the chiefe prince of Meshech and Tubal, and prophecie against him,", "wycliffe": "and he seide, Thou, sone of man, Sette thi face ayens Gog, and ayens the lond of Magog, the prince of the heed of Mosoch and of Tubal; and profesie thou of hym.", "rotherham": "Son of man Set thy face against Gog of the land of the Magog, Prince of Rosh Meshech and Tubal,- And prophesy concerning him,", "darby": "Son of man, set thy face against Gog, the land of Magog, the prince of Rosh, Meshech, and Tubal, and prophesy against him,", "twenty": "", "jps": "'Son of man, set thy face toward Gog, of the land of Magog, the chief prince of Meshech and Tubal, and prophesy against him,", "acv": "Son of man, set thy face toward Gog, of the land of Magog, the ruler of Rosh, Meshech, and Tubal, and prophesy against him.", "anderson": "", "haweis": "", "noyes": "Son of man, set thy face against Gog, of the land of Magog, prince of Resh, Meshech, and Tubal, and prophesy against him,", "webster": "Son of man, set thy face against Gog, the land of Magog, the chief prince of Meshech and Tubal, and prophesy against him.", "vulgate": "fili hominis pone faciem tuam contra Gog terram Magog principem capitis Mosoch et Thubal et vaticinare de eo;", "brenton": "Son of man, set thy face against Gog, and the land of Magog, Rhos, prince of Mesoch and Thobel, and prophesy against him,"}}, {"v": 3, "ref": "38:3", "o": "וְ/אָ֣מַרְתָּ֔ כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הִנְ/נִ֤י אֵלֶ֨י/ךָ֙ גּ֔וֹג נְשִׂ֕יא רֹ֖אשׁ מֶ֥שֶׁךְ וְ/תֻבָֽל", "en": {"kjv": "And say, Thus saith the Lord God; Behold, I am against thee, O Gog, the chief prince of Meshech and Tubal:", "web": "and say, Thus says the Lord Yahweh: Behold, I am against you, Gog, prince of Rosh, Meshech, and Tubal:", "bsb": "and declare that this is what the Lord GOD says: Behold, I am against you, O Gog, chief prince of Meshech and Tubal.", "asv": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Rosh, Meshech, and Tubal:", "ylt": "and thou hast said: Thus saith the Lord Jehovah: Lo, I am against thee, O Gog, Prince of Rosh, Meshech, and Tubal,", "dra": "And say to him: Thus saith the Lord God: Behold, I come against thee, O Gog, the chief prince of Mosoch and Thubal.", "bbe": "And say, This is what the Lord has said: See, I am against you, O Gog, ruler of Rosh, Meshech, and Tubal:", "geneva": "And say, Thus sayth the Lord God, Behold, I come against thee, O Gog the chiefe prince of Meshech and Tubal.", "wycliffe": "And thou schalt seie to hym, The Lord God seith these thingis, A! Gog, lo! Y to thee, prince of the heed of Mosoch and of Tubal;", "rotherham": "and thou shalt say, Thus, saith My Lord Yahweh,— Behold me! against thee O Gog, Prince of Rosh, Meshech and Tubal;", "darby": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Rosh, Meshech, and Tubal.", "twenty": "", "jps": "and say: Thus saith the L-rd GOD: Behold, I am against thee, O Gog, chief prince of Meshech and Tubal;", "acv": "And say, Thus says the lord Jehovah: Behold, I am against thee, O Gog, ruler of Rosh, Meshech, and Tubal.", "anderson": "", "haweis": "", "noyes": "and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Resh, Meshech, and Tubal!", "webster": "And say, Thus saith the Lord GOD: Behold, I [am] against thee, O Gog, the chief prince of Meshech and Tubal:", "vulgate": "et dices ad eum haec dicit Dominus Deus ecce ego ad te Gog principem capitis Mosoch et Thubal;", "brenton": "and say to him, Thus saith the Lord God; Behold, I am against thee, Rhos prince of Mesoch and Thobel:"}}, {"v": 4, "ref": "38:4", "o": "וְ/שׁ֣וֹבַבְתִּ֔י/ךָ וְ/נָתַתִּ֥י חַחִ֖ים בִּ/לְחָיֶ֑י/ךָ וְ/הוֹצֵאתִי֩ אוֹתְ/ךָ֨ וְ/אֶת כָּל חֵילֶ֜/ךָ סוּסִ֣ים וּ/פָרָשִׁ֗ים לְבֻשֵׁ֤י מִכְלוֹל֙ כֻּלָּ֔/ם קָהָ֥ל רָב֙ צִנָּ֣ה וּ/מָגֵ֔ן תֹּפְשֵׂ֥י חֲרָב֖וֹת כֻּלָּֽ/ם", "en": {"kjv": "And I will turn thee back, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them clothed with all sorts of armour, even a great company with bucklers and shields, all of them handling swords:", "web": "and I will turn you around, and put hooks into your jaws, and I will bring you out, with all your army, horses and horsemen, all of them clothed in full armor, a great company with buckler and shield, all of them handling swords;", "bsb": "I will turn you around, put hooks in your jaws, and bring you out with all your army—your horses, your horsemen in full armor, and a great company armed with shields and bucklers, all brandishing their swords.", "asv": "and I will turn thee about, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them clothed in full armor, a great company with buckler and shield, all of them handling swords:", "ylt": "And I have turned thee back, And I have put hooks in thy jaws, And have brought thee out, and all thy force, Horses and horsemen, Clothed in perfection all of them, A numerous assembly, with buckler and shield, Handling swords--all of them.", "dra": "And I will turn thee about, and I will put a bit in thy jaws: and I will bring thee forth, and all thy army, horses and horsemen all clothed with coats of mail, a great multitude, armed with spears and shields and swords.", "bbe": "And turning you round, I will put hooks in your mouth and make you come out with all your army, horses and horsemen, all of them in full war-dress, a great force with breastplate and body-cover, all of them armed with swords:", "geneva": "And I wil destroy thee, and put hookes in thy chawes, and I will bring thee forth, and all thine host both horses, and horsemen, all clothed with al sorts of armour, eue a great multitude with bucklers, and shieldes, all handling swords.", "wycliffe": "and Y schal lede thee aboute, and Y schal sette a bridil in thi chekis, and Y schal leede out thee, and al thin oost, horsis, and horsmen, alle clothid with haburiouns, a greet multitude of men, takynge spere, and scheeld, and swerd.", "rotherham": "Therefore I will turn thee about, and will put hooks in thy jaws,—and bring thee forth and all thine army. Horses and horsemen Clothed with gorgeous attire, all of them, A mighty gathered host With shield and buckler handling swords, all of them:", "darby": "And I will turn thee back, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them thoroughly equipped, a great assemblage with targets and shields, all of them handling swords:", "twenty": "", "jps": "and I will turn thee about, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them clothed most gorgeously, a great company with buckler and shield, all of them handling swords:", "acv": "And I will turn thee about, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them clothed in full armor, a great company with buckler and shield, all of them handling swords,", "anderson": "", "haweis": "", "noyes": "And I will turn thee about, and put rings into thy jaws; and I will bring thee forth, thee and all thine army, horses and horsemen, all of them clothed in gorgeous apparel, even a great multitude with bucklers and shields, all of them handling swords.", "webster": "And I will turn thee back, and put hooks into thy jaws, and I will bring thee forth, and all thy army, horses and horsemen, all of them clothed with all sorts [of armor], [even] a great company [with] bucklers and shields, all of them handling swords:", "vulgate": "et circumagam te et ponam frenum in maxillis tuis et educam te et omnem exercitum tuum equos et equites vestitos loricis universos multitudinem magnam hastam et clypeum arripientium et gladium;", "brenton": "and I will gather thee, and all thine host, horses and horsemen, all wearing breast-plates, with a great multitude, shields and helmets and swords:"}}, {"v": 5, "ref": "38:5", "o": "פָּרַ֛ס כּ֥וּשׁ וּ/פ֖וּט אִתָּ֑/ם כֻּלָּ֖/ם מָגֵ֥ן וְ/כוֹבָֽע", "en": {"kjv": "Persia, Ethiopia, and Libya with them; all of them with shield and helmet:", "web": "Persia, Cush, and Put with them, all of them with shield and helmet;", "bsb": "Persia, Cush, and Put will accompany them, all with shields and helmets,", "asv": "Persia, Cush, and Put with them, all of them with shield and helmet;", "ylt": "Persia, Cush, and Phut, with them, All of them with shield and helmet.", "dra": "The Persians, Ethiopians, and Libyans with them, all with shields and helmets.", "bbe": "Persia, Cush, and Put with them; all of them with body-cover and metal head-dress:", "geneva": "They of Paras, of Cush, and Phut with the, euen all they that beare shielde and helmet.", "wycliffe": "Perseis, Ethiopiens, and Libiens with hem, alle ben araied with scheeldis and helmes.", "rotherham": "Persia Ethiopia and Libya with them, All of them, with shield and helmet;", "darby": "Persia, Cush, and Phut with them, all of them with shield and helmet;", "twenty": "", "jps": "Persia, Cush, and Put with them, all of them with shield and helmet;", "acv": "Persia, Cush, and Put with them, all of them with shield and helmet,", "anderson": "", "haweis": "", "noyes": "Persians, Ethiopians, and Lybians are with them, all of them with shields and helmets.", "webster": "Persia, Cush, and Phut with them; all of them with shield and helmet:", "vulgate": "Persae Aethiopes et Lybies cum eis omnes scutati et galeati;", "brenton": "Persians, and Ethiopians, and Libyans; all with helmets and shields."}}, {"v": 6, "ref": "38:6", "o": "גֹּ֚מֶר וְ/כָל אֲגַפֶּ֔י/הָ בֵּ֚ית תּֽוֹגַרְמָ֔ה יַרְכְּתֵ֥י צָפ֖וֹן וְ/אֶת כָּל אֲגַפָּ֑י/ו עַמִּ֥ים רַבִּ֖ים אִתָּֽ/ךְ", "en": {"kjv": "Gomer, and all his bands; the house of Togarmah of the north quarters, and all his bands: and many people with thee.", "web": "Gomer, and all his hordes; the house of Togarmah in the uttermost parts of the north, and all his hordes; even many peoples with you.", "bsb": "as well as Gomer with all its troops, and Beth-togarmah from the far north with all its troops—the many nations with you.", "asv": "Gomer, and all his hordes; the house of Togarmah in the uttermost parts of the north, and all his hordes; even many peoples with thee.", "ylt": "Gomer and all its bands, The house of Togarmah of the sides of the north, And all its bands, many peoples with thee,", "dra": "Gomer, and all his bands, the house of Thogorma, the northern parts and all his strength, and many peoples with thee.", "bbe": "Gomer and all her forces; the people of Togarmah in the inmost parts of the north, with all his forces: a great number of peoples with you.", "geneva": "Gomer and all his bands, and the house of Togarmah of the North quarters, and al his bands, and much people with thee.", "wycliffe": "Gomer, and alle the cumpenyes of hym, the hous of Togorma, the sidis of the north, and al the strengthe therof, and many puplis ben with thee.", "rotherham": "Gomer and all her hordes, The house of Togarmah the remote men of the North and all his hordes, Many peoples with thee.", "darby": "Gomer, and all his bands; the house of Togarmah from the uttermost north, and all his bands; — many peoples with thee.", "twenty": "", "jps": "Gomer, and all his bands; the house of Togarmah in the uttermost parts of the north, and all his bands; even many peoples with thee.", "acv": "Gomer, and all his hordes, the house of Togarmah in the outermost parts of the north, and all his hordes, even many peoples with thee.", "anderson": "", "haweis": "", "noyes": "Gomer and all his bands, the house of Togarmah from the north quarters, and all their hosts, many nations are with thee.", "webster": "Gomer, and all his bands; the house of Togarmah of the north quarters, and all his bands: [and] many people with thee.", "vulgate": "Gomer et universa agmina eius domus Thogorma latera aquilonis et totum robur eius populique multi tecum;", "brenton": "Gomer, and all belonging to him; the house of Thorgama, from the end of the north, and all belonging to him; and many nations with thee."}}, {"v": 7, "ref": "38:7", "o": "הִכֹּן֙ וְ/הָכֵ֣ן לְ/ךָ֔ אַתָּ֕ה וְ/כָל קְהָלֶ֖/ךָ הַ/נִּקְהָלִ֣ים עָלֶ֑י/ךָ וְ/הָיִ֥יתָ לָ/הֶ֖ם לְ/מִשְׁמָֽר", "en": {"kjv": "Be thou prepared, and prepare for thyself, thou, and all thy company that are assembled unto thee, and be thou a guard unto them.", "web": "Be prepared, yes, prepare yourself, you, and all your companies who are assembled to you, and be a guard to them.", "bsb": "Get ready; prepare yourself, you and all your company gathered around you; you will be their guard.", "asv": "Be thou prepared, yea, prepare thyself, thou, and all thy companies that are assembled unto thee, and be thou a guard unto them.", "ylt": "Be prepared, yea, prepare for thee, Thou and all thine assemblies who are assembled unto thee, And thou hast been to them for a guard.", "dra": "Prepare and make thyself ready, and all thy multitude that is assembled about thee, and be thou commander over them.", "bbe": "Be ready, make yourself ready, you and all the forces who are with you, and be ready for my orders.", "geneva": "Prepare thy selfe, and make thee ready, both thou, and al thy multitude, that are assembled vnto thee, and be thou their sauegard.", "wycliffe": "Make redi, and araye thee, and al thi multitude which is gaderid to thee, and be thou in to comaundement to hem.", "rotherham": "Be ready, and show thyself ready, Thou and all thy gathered host who have gathered themselves unto thee,— And become thou for me a guard.", "darby": "Be thou prepared, and prepare for thyself thou, and all thine assemblage that are assembled unto thee, and be thou a guard unto them.", "twenty": "", "jps": "Be thou prepared, and prepare for thyself, thou, and all thy company that are assembled unto thee, and be thou guarded of them.", "acv": "Be thou prepared. Yea, prepare thyself, thou, and all thy companies that are assembled to thee, and be thou a guard to them.", "anderson": "", "haweis": "", "noyes": "Be prepared, and prepare for thyself, thou and all thy host that are assembled unto thee, and be thou their leader!", "webster": "Be thou prepared, and prepare for thyself, thou, and all thy company that are assembled to thee, and be thou a guard to them.", "vulgate": "praepara et instrue te et omnem multitudinem tuam quae coacervata est ad te et esto eis in praeceptum;", "brenton": "Be thou prepared, prepare thyself, thou, and all thy multitude that is assembled with thee, and thou shalt be to me for a guard."}}, {"v": 8, "ref": "38:8", "o": "מִ/יָּמִ֣ים רַבִּים֮ תִּפָּקֵד֒ בְּ/אַחֲרִ֨ית הַ/שָּׁנִ֜ים תָּב֣וֹא אֶל אֶ֣רֶץ מְשׁוֹבֶ֣בֶת מֵ/חֶ֗רֶב מְקֻבֶּ֨צֶת֙ מֵ/עַמִּ֣ים רַבִּ֔ים עַ֚ל הָרֵ֣י יִשְׂרָאֵ֔ל אֲשֶׁר הָי֥וּ לְ/חָרְבָּ֖ה תָּמִ֑יד וְ/הִיא֙ מֵ/עַמִּ֣ים הוּצָ֔אָה וְ/יָשְׁב֥וּ לָ/בֶ֖טַח כֻּלָּֽ/ם", "en": {"kjv": "After many days thou shalt be visited: in the latter years thou shalt come into the land that is brought back from the sword, and is gathered out of many people, against the mountains of Israel, which have been always waste: but it is brought forth out of the nations, and they shall dwell safely all of them.", "web": "After many days you shall be visited: in the latter years you shall come into the land that is brought back from the sword, that is gathered out of many peoples, on the mountains of Israel, which have been a continual waste; but it is brought out of the peoples, and they shall dwell securely, all of them.", "bsb": "After a long time you will be summoned. In the latter years you will enter a land that has recovered from war, whose people were gathered from many nations to the mountains of Israel, which had long been desolate. They had been brought out from the nations, and all now dwell securely.", "asv": "After many days thou shalt be visited: in the latter years thou shalt come into the land that is brought back from the sword, that is gathered out of many peoples, upon the mountains of Israel, which have been a continual waste; but it is brought forth out of the peoples, and they shall dwell securely, all of them.", "ylt": "After many days thou art appointed, In the latter end of the years thou comest in unto a land brought back from sword, A people gathered out of many peoples, Upon mountains of Israel, That have been for a perpetual waste, And it from the peoples hath been brought out, And dwelt safely have all of them.", "dra": "After many days thou shalt be visited: at the end of years thou shalt come to the land that is returned from the sword, and is gathered out of many nations, to the mountains of Israel which have been continually waste: but it hath been brought forth out of the nations, and they shall all of them dwell securely in it.", "bbe": "After a long time you will get your orders: in the last years you will come into the land which has been given back from the sword, which has been got together out of a great number of peoples, on the mountains of Israel which have ever been a waste: but it has been taken out from the peoples and they will be living, all of them, without fear of danger.", "geneva": "After many dayes thou shalt bee visited: for in the latter yeres thou shalt come into the land, that hath bene destroyed with the sworde, and is gathered out of many people vpon the mountaines of Israel, which haue long lien waste: yet they haue bene brought out of the people, and they shall dwell all safe.", "wycliffe": "Aftir many daies thou schalt be visitid, in the laste of yeeris thou schalt come to the lond, that turnede ayen fro swerd, and was gaderid of many puplis, to the hillis of Israel that weren desert ful ofte; this was led out of puplis, and alle men dwellide tristili ther ynne.", "rotherham": "After many days, shalt thou muster thy forces, In the afterpart of the years, shalt thou enter Into the land of the remnant brought back from the sword Gathered from among many peoples, Upon the mountains of Israel which have been waste continually,— But the same! from among the peoples, hath been brought forth, And they shall dwell in security, all of them.", "darby": "After many days shalt thou be visited; at the end of years thou shalt come into the land brought back from the sword [and] gathered out of many peoples, upon the mountains of Israel which have been a perpetual waste: but it is brought forth out from the peoples, and they shall all of them be dwelling in safety.", "twenty": "", "jps": "After many days thou shalt be mustered for service, in the latter years thou shalt come against the land that is brought back from the sword, that is gathered out of many peoples, against the mountains of Israel, which have been a continual waste; but it is brought forth out of the peoples, and they dwell safely all of them.", "acv": "After many days thou shall be visited. In the latter years thou shall come into the land that is brought back from the sword, that is gathered out of many peoples, upon the mountains of Israel, which have been a continual waste, but it is brought forth out of the peoples, and they shall dwell securely, all of them.", "anderson": "", "haweis": "", "noyes": "After many days shalt thou be appointed over them. In the latter years shalt thou come into a land that is brought back from the sword, gathered out of many nations upon the mountains of Israel, which had been long desolate; but it is brought forth out of the nations, and they shall dwell securely, all of them.", "webster": "After many days thou shalt be visited: in the latter years thou shalt come into the land [that is] brought back from the sword, [and is] gathered out of many people, against the mountains of Israel, which have been always waste: but it is brought forth out of the nations, and they shall all dwell in safety.", "vulgate": "post dies multos visitaberis in novissimo annorum venies ad terram quae reversa est a gladio congregata est de populis multis ad montes Israhel qui fuerunt deserti iugiter haec de populis educta est et habitaverunt in ea confidenter universi;", "brenton": "He shall be prepared after many days, and he shall come at the end of years, and shall come to a land that is brought back from the sword, when the people are gathered from many nations against the land of Israel, which was entirely desolate: and he is come forth out of the nations, and they shall all dwell securely."}}, {"v": 9, "ref": "38:9", "o": "וְ/עָלִ֨יתָ֙ כַּ/שֹּׁאָ֣ה תָב֔וֹא כֶּ/עָנָ֛ן לְ/כַסּ֥וֹת הָ/אָ֖רֶץ תִּֽהְיֶ֑ה אַתָּה֙ וְ/כָל אֲגַפֶּ֔י/ךָ וְ/עַמִּ֥ים רַבִּ֖ים אוֹתָֽ/ךְ", "en": {"kjv": "Thou shalt ascend and come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy bands, and many people with thee.", "web": "You shall ascend, you shall come like a storm, you shall be like a cloud to cover the land, you, and all your hordes, and many peoples with you.", "bsb": "You and all your troops, and many peoples with you will go up, advancing like a thunderstorm; you will be like a cloud covering the land.", "asv": "And thou shalt ascend, thou shalt come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy hordes, and many peoples with thee.", "ylt": "And thou hast gone up--as wasting thou comest in, As a cloud to cover the land art thou, Thou and all thy bands, and many peoples with thee.", "dra": "And thou shalt go up and come like a storm, and like a cloud to cover the land, thou and all thy bands and many people with thee.", "bbe": "And you will go up, you will come like a storm, you will be like a cloud covering the land, you and all your forces, and a great number of peoples with you.", "geneva": "Thou shalt ascende and come vp like a tempest, and shalt be like a cloude to couer the land, both thou, and all thy bandes, and many people with thee.", "wycliffe": "Forsothe thou schalt stie, and schalt come as a tempest, and as a cloude, for to hile the lond, thou, and alle thi cumpanyes, and many puplis with thee.", "rotherham": "Then shalt thou come up, Like a storm, shalt thou enter, Like a cloud covering the land, shalt thou be,— Thou and all thy hordes, and many peoples with thee.", "darby": "And thou shalt ascend, thou shalt come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy bands, and many peoples with thee.", "twenty": "", "jps": "And thou shalt ascend, thou shalt come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy bands, and many peoples with thee.", "acv": "And thou shall ascend. Thou shall come like a storm. Thou shall be like a cloud to cover the land, thou, and all thy hordes, and many peoples with thee.", "anderson": "", "haweis": "", "noyes": "Thou shalt go up like a storm, thou shalt come like a cloud, to cover the land, thou and all thy bands, and many nations with thee.", "webster": "Thou shalt ascend and come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy bands, and many people with thee.", "vulgate": "ascendens autem quasi tempestas venies et quasi nubes ut operias terram tu et omnia agmina tua et populi multi tecum;", "brenton": "And thou shalt go up as rain, and shalt arrive as a cloud to cover the land, and there shall be thou, and all that are about thee, and many nations with thee."}}, {"v": 10, "ref": "38:10", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא יַעֲל֤וּ דְבָרִים֙ עַל לְבָבֶ֔/ךָ וְ/חָשַׁבְתָּ֖ מַחֲשֶׁ֥בֶת רָעָֽה", "en": {"kjv": "Thus saith the Lord God; It shall also come to pass, that at the same time shall things come into thy mind, and thou shalt think an evil thought:", "web": "Thus says the Lord Yahweh: It shall happen in that day, that things shall come into your mind, and you shall devise an evil device:", "bsb": "This is what the Lord GOD says: On that day, thoughts will arise in your mind, and you will devise an evil plan.", "asv": "Thus saith the Lord Jehovah: It shall come to pass in that day, that things shall come into thy mind, and thou shalt devise an evil device:", "ylt": "Thus said the Lord Jehovah: And it hath come to pass in that day, Come up do things on thy heart, And thou hast thought an evil thought,", "dra": "Thus saith the Lord God: In that day projects shall enter into thy heart, and thou shalt conceive a mischievous design.", "bbe": "This is what the Lord has said: In that day it will come about that things will come into your mind, and you will have thoughts of an evil design:", "geneva": "Thus saith the Lord God, Euen at ye same time shall many things come into thy minde, and thou shalt thinke euil thoughts.", "wycliffe": "The Lord God seith these thingis, In that dai wordis schulen stie on thin herte, and thou schalt thenke the worste thouyt;", "rotherham": "Thus saith My Lord, Yahweh,— So shall it be in that day, that thoughts will come up on thy heart.- And thou wilt devise a wicked device;", "darby": "Thus saith the Lord Jehovah: It shall even come to pass in that day that things shall come into thy mind, and thou shalt think an evil thought;", "twenty": "", "jps": "Thus saith the L-rd GOD: It shall come to pass in that day, that things shall come into thy mind, and thou shalt devise an evil device;", "acv": "Thus says the lord Jehovah: It shall come to pass in that day, that things shall come into thy mind, and thou shall devise an evil plan.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: At the same time shall thoughts come into thy mind, and thou shalt meditate an evil design,", "webster": "Thus saith the Lord GOD; It shall also come to pass, [that] at the same time shall things come into thy mind, and thou shalt think an evil thought:", "vulgate": "haec dicit Dominus Deus in die illa ascendent sermones super cor tuum et cogitabis cogitationem pessimam;", "brenton": "Thus saith the Lord God; It shall also come to pass in that day, that thoughts shall come up into thine heart, and thou shalt devise evil devices."}}, {"v": 11, "ref": "38:11", "o": "וְ/אָמַרְתָּ֗ אֶֽעֱלֶה֙ עַל אֶ֣רֶץ פְּרָז֔וֹת אָבוֹא֙ הַ/שֹּׁ֣קְטִ֔ים יֹשְׁבֵ֖י לָ/בֶ֑טַח כֻּלָּ֗/ם יֹֽשְׁבִים֙ בְּ/אֵ֣ין חוֹמָ֔ה וּ/בְרִ֥יחַ וּ/דְלָתַ֖יִם אֵ֥ין לָ/הֶֽם", "en": {"kjv": "And thou shalt say, I will go up to the land of unwalled villages; I will go to them that are at rest, that dwell safely, all of them dwelling without walls, and having neither bars nor gates,", "web": "and you shall say, I will go up to the land of unwalled villages; I will go to those who are at rest, who dwell securely, all of them dwelling without walls, and having neither bars nor gates;", "bsb": "You will say, ‘I will go up against a land of unwalled villages; I will come against a tranquil people who dwell securely, all of them living without walls or bars or gates—", "asv": "and thou shalt say, I will go up to the land of unwalled villages; I will go to them that are at rest, that dwell securely, all of them dwelling without walls, and having neither bars nor gates;", "ylt": "And thou hast said: I go up against a land of unwalled villages, I go in to those at rest, dwelling confidently, All of them are dwelling without walls, And bar and doors they have not.", "dra": "And thou shalt say: I will go up to the land which is without a wall, I will come to them that are at rest, and dwell securely: all these dwell without a wall, they have no bars nor gates:", "bbe": "And you will say, I will go up to the land of small unwalled towns; I will go to those who are quiet, living, all of them, without fear of danger, without walls or locks or doors:", "geneva": "And thou shalt say, I wil go vp to the land that hath no walled towres: I will goe to them that are at rest, and dwell in safetie, which dwell all without walles, and haue neither barres nor gates,", "wycliffe": "and schalt seie, Y schal stie to the lond with out wal, and Y schal come to hem that resten and dwellen sikirli; alle these dwellen with out wal, barris and yatis ben not to hem;", "rotherham": "and wilt say— I will go up over a land of hamlets, I will enter among them who are at rest dwelling securely,— All of them, dwelling without a wall, Who bars and doors, have none;", "darby": "and thou shalt say, I will go up to the land of unwalled villages; I will come to them that are in quiet, that dwell in safety, all of them dwelling without walls, and having neither bars nor gates,", "twenty": "", "jps": "and thou shalt say: I will go up against the land of unwalled villages; I will come upon them that are at quiet, that dwell safely, all of them dwelling without walls, and having neither bars nor gates;", "acv": "And thou shall say, I will go up to the land of unwalled villages. I will go to those who are at rest, who dwell securely, all of them dwelling without walls, and having neither bars nor gates,", "anderson": "", "haweis": "", "noyes": "and shalt say, \"I will go up to the land of unwalled villages; I will go to them that are at rest, that dwell securely, all of them dwelling without walls, and having neither bars nor gates,", "webster": "And thou shalt say, I will go up to the land of unwalled villages; I will go to them that are at rest, that dwell safely, all of them dwelling without walls, and having neither bars nor gates,", "vulgate": "et dices ascendam ad terram absque muro veniam ad quiescentes habitantesque secure omnes habitant sine muro vectes et portae non sunt eis;", "brenton": "And thou shalt say, I will go up to the rejected land; I will come upon them that are at ease in tranquility, and dwelling in peace, all inhabiting a land in which there is no wall, nor bars, nor have they doors;"}}, {"v": 12, "ref": "38:12", "o": "לִ/שְׁלֹ֥ל שָׁלָ֖ל וְ/לָ/בֹ֣ז בַּ֑ז לְ/הָשִׁ֨יב יָדְ/ךָ֜ עַל חֳרָב֣וֹת נוֹשָׁבֹ֗ת וְ/אֶל עַם֙ מְאֻסָּ֣ף מִ/גּוֹיִ֔ם עֹשֶׂה֙ מִקְנֶ֣ה וְ/קִנְיָ֔ן יֹשְׁבֵ֖י עַל טַבּ֥וּר הָ/אָֽרֶץ", "en": {"kjv": "To take a spoil, and to take a prey; to turn thine hand upon the desolate places that are now inhabited, and upon the people that are gathered out of the nations, which have gotten cattle and goods, that dwell in the midst of the land.", "web": "to take the plunder and to take the prey; to turn your hand against the waste places that are inhabited, and against the people who are gathered out of the nations, who have gotten livestock and goods, who dwell in the middle of the earth.", "bsb": "in order to seize the spoil and carry off the plunder, to turn a hand against the desolate places now inhabited and against a people gathered from the nations, who have acquired livestock and possessions and who live at the center of the land.’", "asv": "to take the spoil and to take the prey; to turn thy hand against the waste places that are now inhabited, and against the people that are gathered out of the nations, that have gotten cattle and goods, that dwell in the middle of the earth.", "ylt": "To take a spoil, and to take a prey, To turn back thy hand on inhabited wastes, And on a people gathered out of nations, Making cattle and substance, Dwelling on a high part of the land.", "dra": "To take spoils, and lay hold on the prey, to lay thy hand upon them that had been wasted, and afterwards restored, and upon the people that is gathered together out of the nations, which hath begun to possess and to dwell in the midst of the earth.", "bbe": "To take their property by force and go off with their goods; turning your hand against the waste places which now are peopled, and against the people who have been got together out of the nations, who have got cattle and goods for themselves, who are living in the middle of the earth.", "geneva": "Thinking to spoyle the pray, and to take a bootie, to turne thine hande vpon the desolate places that are nowe inhabited, and vpon the people, that are gathered out of the nations which haue gotten cattell and goods, and dwell in the middes of the land.", "wycliffe": "that thou rauysche spuylis, and asaile prei; that thou brynge in thin hond on hem that weren forsakun, and afterward restorid, and on the puple which is gaderid of hethene men, that bigan to welde, and to be enhabitere of the nawle of erthe.", "rotherham": "To capture spoil. And take prey,- To bring back thy hand over desolate places at length inhabited And against a people gathered from among the nations, Getting herds and substance Dwelling upon the navel of the earth.", "darby": "to seize a spoil, and to take a prey; to turn thy hand against the waste places that are [now] inhabited, and against a people gathered out of the nations, which have gotten cattle and goods, that dwell in the middle of the land.", "twenty": "", "jps": "to take the spoil and to take the prey; to turn thy hand against the waste places that are now inhabited, and against the people that are gathered out of the nations, that have gotten cattle and goods, that dwell in the middle of the earth.", "acv": "to take the spoil and to take the prey, to turn thy hand against the waste places that are now inhabited, and against the people who are gathered out of the nations, who have gotten cattle and goods, who dwell in the middle of the earth.", "anderson": "", "haweis": "", "noyes": "to take a spoil and to divide a prey, to turn my hand against the desolated places that have become inhabited, and against a people gathered out of the nations, possessing cattle and goods, dwelling in the heights of the earth.\"", "webster": "To take a spoil, and to take a prey; to turn thy hand upon the desolate places [that are now] inhabited, and upon the people [that are] gathered out of the nations, which have gotten cattle and goods, that dwell in the midst of the land.", "vulgate": "ut diripias spolia et invadas praedam ut inferas manum tuam super eos qui deserti fuerant et postea restituti et super populum qui est congregatus ex gentibus qui possidere coepit et esse habitator umbilici terrae;", "brenton": "to seize plunder, and to take their spoil; to turn my hands against the desolate land that is now inhabited, and against a nation that is gathered from many nations, that have acquired property, dwelling in the midst of the land."}}, {"v": 13, "ref": "38:13", "o": "שְׁבָ֡א וּ֠/דְדָן וְ/סֹחֲרֵ֨י תַרְשִׁ֤ישׁ וְ/כָל כְּפִרֶ֨י/הָ֙ יֹאמְר֣וּ לְ/ךָ֔ הֲ/לִ/שְׁלֹ֤ל שָׁלָל֙ אַתָּ֣ה בָ֔א הֲ/לָ/בֹ֥ז בַּ֖ז הִקְהַ֣לְתָּ קְהָלֶ֑/ךָ לָ/שֵׂ֣את כֶּ֣סֶף וְ/זָהָ֗ב לָ/קַ֨חַת֙ מִקְנֶ֣ה וְ/קִנְיָ֔ן לִ/שְׁלֹ֖ל שָׁלָ֥ל גָּדֽוֹל", "en": {"kjv": "Sheba, and Dedan, and the merchants of Tarshish, with all the young lions thereof, shall say unto thee, Art thou come to take a spoil? hast thou gathered thy company to take a prey? to carry away silver and gold, to take away cattle and goods, to take a great spoil?", "web": "Sheba, and Dedan, and the merchants of Tarshish, with all the young lions of it, shall tell you, Have you come to take the plunder? have you assembled your company to take the prey? to carry away silver and gold, to take away livestock and goods, to take great plunder?", "bsb": "Sheba and Dedan and the merchants of Tarshish with all its villages will ask, ‘Have you come to capture the plunder? Have you assembled your hordes to carry away loot, to make off with silver and gold, to take cattle and goods, to seize great spoil?’", "asv": "Sheba, and Dedan, and the merchants of Tarshish, with all the young lions thereof, shall say unto thee, Art thou come to take the spoil? hast thou assembled thy company to take the prey? to carry away silver and gold, to take away cattle and goods, to take great spoil?", "ylt": "Sheba, and Dedan, and merchants of Tarshish, And all its young lions say to thee: To take a spoil art thou come in? To take a prey assembled thine assembly? To bear away silver and gold? To take away cattle and substance? To take a great spoil?", "dra": "Saba, and Dedan, and the merchants of Tharsis, and all the lions thereof shall say to thee: Art thou come to take spoils? behold, thou hast gathered thy multitude to take a prey, to take silver, and gold, and to carry away goods and substance, and to take rich spoils.", "bbe": "Sheba, and Dedan and her traders, Tarshish with all her traders, will say to you, Have you come to take our goods? have you got your armies together to take away our property by force? to take away silver and gold, cattle and goods, to go off with great wealth?", "geneva": "Sheba and Dedan, and the marchantes of Tarshish with all the lions thereof shall say vnto thee, Art thou come to spoyle the praye? hast thou gathered thy multitude to take a booty? to cary away siluer and golde, to take away cattell and goods, and to spoyle a great pray?", "wycliffe": "Saba, and Dedan, and the marchauntis of Tharsis, and alle the liouns therof schulen seie to thee, Whether thou comest to take spuylis? Lo! to rauysche prey thou hast gaderid thi multitude, that thou take awei gold and siluer, and do awei purtenaunce of houshold and catel, and that thou rauysche preyes with out noumbre.", "rotherham": "Sheba and Dedan and the traders of Tarshish and all her young lions, will say to thee, To capture spoil, art thou coming? And to take prey, hast thou called together thy gathered host? To carry off silver and gold To take away herds and substance, To capture great spoil?", "darby": "Sheba, and Dedan, and the merchants of Tarshish, with all the young lions thereof, shall say unto thee, Art thou come to seize a spoil? hast thou gathered thine assemblage to take a prey? to carry away silver and gold, to take cattle and goods, to seize a great spoil?", "twenty": "", "jps": "Sheba, and Dedan, and the merchants of Tarshish, with all the magnates thereof, shall say unto thee: Comest thou to take the spoil? hast thou assembled thy company to take the prey? to carry away silver and gold, to take away cattle and goods, to take great spoil?", "acv": "Sheba, and Dedan, and the merchants of Tarshish, with all the young lions of it, shall say to thee, Have thou come to take the spoil? Have thou assembled thy company to take the prey, to carry away silver and gold, to take away cattle and goods, to take great spoil?", "anderson": "", "haweis": "", "noyes": "Sheba, and Dedan, and the merchants of Tarshish, and all the chiefs thereof, shall say to thee, \"Art thou come to take a spoil? Hast thou gathered thy company to divide a prey? to carry away silver and gold, to take away cattle and goods, and to divide great spoil?\"", "webster": "Sheba, and Dedan, and the merchants of Tarshish, with all its young lions, shall say to thee, Art thou come to take a spoil? hast thou gathered thy company to take a prey? to carry away silver and gold, to take away cattle and goods, to take a great spoil?", "vulgate": "Seba et Dedan et negotiatores Tharsis et omnes leones eius dicent tibi numquid ad sumenda spolia tu venis ecce ad diripiendam praedam congregasti multitudinem tuam ut tollas argentum et aurum auferas supellectilem atque substantiam et diripias manubias infinitas;", "brenton": "Sabba, and Daedan, and Carthaginian merchants, and all their villages shall say to thee, Thou art come for plunder to take a prey, and to get spoils: thou hast gathered thy multitude to take silver and gold, to carry off property, to take spoils."}}, {"v": 14, "ref": "38:14", "o": "לָ/כֵן֙ הִנָּבֵ֣א בֶן אָדָ֔ם וְ/אָמַרְתָּ֣ לְ/ג֔וֹג כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הֲ/ל֣וֹא בַּ/יּ֣וֹם הַ/ה֗וּא בְּ/שֶׁ֨בֶת עַמִּ֧/י יִשְׂרָאֵ֛ל לָ/בֶ֖טַח תֵּדָֽע", "en": {"kjv": "Therefore, son of man, prophesy and say unto Gog, Thus saith the Lord God; In that day when my people of Israel dwelleth safely, shalt thou not know it?", "web": "Therefore, son of man, prophesy, and tell Gog, Thus says the Lord Yahweh: In that day when my people Israel dwells securely, shall you not know it?", "bsb": "Therefore prophesy, son of man, and tell Gog that this is what the Lord GOD says: On that day when My people Israel are dwelling securely, will you not take notice of this?", "asv": "Therefore, son of man, prophesy, and say unto Gog, Thus saith the Lord Jehovah: In that day when my people Israel dwelleth securely, shalt thou not know it?", "ylt": "Therefore, prophesy, son of man, and thou hast said to Gog: Thus said the Lord Jehovah: In that day, in the dwelling of My people Israel safely, Dost thou not know?", "dra": "Therefore, thou son of man, prophesy and say to Gog: Thus saith the Lord God: Shalt thou not know, in that day, when my people of Israel shall dwell securely?", "bbe": "For this cause, son of man, be a prophet and say to Gog, These are the words of the Lord: In that day, when my people Israel are living without fear of danger, will you not be moved against them?", "geneva": "Therefore, sonne of man, prophecie, and saye vnto Gog, Thus sayeth the Lord God, In that day when my people of Israel dwelleth safe, shalt thou not knowe it?", "wycliffe": "Therfor profesie thou, sone of man; and thou schalt seie to Gog, The Lord God seith these thingis, Whether not in that dai, whanne my puple Israel schal dwelle tristili, thou schalt wite;", "rotherham": "Therefore prophesy, Son of man, and thou shalt say to Gog. Thus saith My Lord, Yahweh: Shall it not be in that day, because my people Israel are dwelling securely:, that thou wilt rouse thyself?", "darby": "Therefore prophesy, son of man, and say unto Gog, Thus saith the Lord Jehovah: In that day when my people Israel dwelleth in safety, shalt thou not know [it]?", "twenty": "", "jps": "Therefore, son of man, prophesy, and say unto Gog: Thus saith the L-rd GOD: In that day when My people Israel dwelleth safely, shalt thou not know it?", "acv": "Therefore, son of man, prophesy, and say to Gog, Thus says the lord Jehovah: In that day when my people Israel dwell securely, shall thou not know it?", "anderson": "", "haweis": "", "noyes": "Therefore prophesy, son of man, and say to Gog, Thus saith the Lord Jehovah: In that day when my people Israel dwelleth securely, thou shalt observe it,", "webster": "Therefore, son of man, prophesy and say to Gog, Thus saith the Lord GOD; In that day when my people of Israel dwelleth safely, shalt thou not know [it]?", "vulgate": "propterea vaticinare fili hominis et dices ad Gog haec dicit Dominus Deus numquid non in die illo cum habitaverit populus meus Israhel confidenter scies;", "brenton": "Therefore prophesy, son of man, and say to Gog, Thus saith the Lord; Wilt thou not arise in that day, when my people Israel are dwelling securely,"}}, {"v": 15, "ref": "38:15", "o": "וּ/בָ֤אתָ מִ/מְּקֽוֹמְ/ךָ֙ מִ/יַּרְכְּתֵ֣י צָפ֔וֹן אַתָּ֕ה וְ/עַמִּ֥ים רַבִּ֖ים אִתָּ֑/ךְ רֹכְבֵ֤י סוּסִים֙ כֻּלָּ֔/ם קָהָ֥ל גָּד֖וֹל וְ/חַ֥יִל רָֽב", "en": {"kjv": "And thou shalt come from thy place out of the north parts, thou, and many people with thee, all of them riding upon horses, a great company, and a mighty army:", "web": "You shall come from your place out of the uttermost parts of the north, you, and many peoples with you, all of them riding on horses, a great company and a mighty army;", "bsb": "And you will come from your place out of the far north—you and many peoples with you, all riding horses—a mighty horde, a huge army.", "asv": "And thou shalt come from thy place out of the uttermost parts of the north, thou, and many peoples with thee, all of them riding upon horses, a great company and a mighty army;", "ylt": "And thou hast come in out of thy place, From the sides of the north, Thou and many peoples with thee, Riding on horses--all of them, A great assembly, and a numerous force.", "dra": "And thou shalt come out of thy place from the northern parts, thou and many people with thee, all of them riding upon horses, a great company and a mighty army.", "bbe": "And you will come from your place in the inmost parts of the north, you and a great number of peoples with you, all of them on horseback, a great force and a strong army:", "geneva": "And come from thy place out of the North partes, thou and much people with thee? all shall ride vpon horses, euen a great multitude and a mightie armie.", "wycliffe": "and schalt come fro thi place, fro the sidis of the north, thou, and many puplis with thee, alle stieris of horsis, a greet cumpany, and an huge oost;", "rotherham": "Therefore wilt thou come out of thy place. Out of the remote parts of the North, Thou and many peoples with thee,—Riding on horses all of them, A mighty gathered host. Yea a great army;", "darby": "And thou shalt come from thy place out of the uttermost north, thou and many peoples with thee, all of them riding upon horses, a great assemblage and a mighty army.", "twenty": "", "jps": "And thou shalt come from thy place out of the uttermost parts of the north, thou, and many peoples with thee, all of them riding upon horses, a great company and a mighty army;", "acv": "And thou shall come from thy place out of the outermost parts of the north, thou, and many peoples with thee, all of them riding upon horses, a great company and a mighty army.", "anderson": "", "haweis": "", "noyes": "and thou shalt come up from the regions of the North, thou and many nations with thee, all of them riding upon horses, a great company, and a mighty host;", "webster": "And thou shalt come from thy place out of the north parts, thou, and many people with thee, all of them riding upon horses, a great company, and a mighty army:", "vulgate": "et venies de loco tuo a lateribus aquilonis tu et populi multi tecum ascensores equorum universi coetus magnus et exercitus vehemens;", "brenton": "and come out of thy place from the farthest north, and many nations with thee? all of them mounted on horses, a great gathering, and a large force?"}}, {"v": 16, "ref": "38:16", "o": "וְ/עָלִ֨יתָ֙ עַל עַמִּ֣/י יִשְׂרָאֵ֔ל כֶּֽ/עָנָ֖ן לְ/כַסּ֣וֹת הָ/אָ֑רֶץ בְּ/אַחֲרִ֨ית הַ/יָּמִ֜ים תִּֽהְיֶ֗ה וַ/הֲבִאוֹתִ֨י/ךָ֙ עַל אַרְצִ֔/י לְמַעַן֩ דַּ֨עַת הַ/גּוֹיִ֜ם אֹתִ֗/י בְּ/הִקָּדְשִׁ֥/י בְ/ךָ֛ לְ/עֵינֵי/הֶ֖ם גּֽוֹג", "en": {"kjv": "And thou shalt come up against my people of Israel, as a cloud to cover the land; it shall be in the latter days, and I will bring thee against my land, that the heathen may know me, when I shall be sanctified in thee, O Gog, before their eyes.", "web": "and you shall come up against my people Israel, as a cloud to cover the land: it shall happen in the latter days, that I will bring you against my land, that the nations may know me, when I shall be sanctified in you, Gog, before their eyes.", "bsb": "You will advance against My people Israel like a cloud covering the land. It will happen in the latter days, O Gog, that I will bring you against My land, so that the nations may know Me when I show Myself holy in you before their eyes.", "asv": "and thou shalt come up against my people Israel, as a cloud to cover the land: it shall come to pass in the latter days, that I will bring thee against my land, that the nations may know me, when I shall be sanctified in thee, O Gog, before their eyes.", "ylt": "And thou hast come up against My people Israel, As a cloud to cover the land, In the latter end of the days it is, And I have brought thee in against My land, In order that the nations may know Me, In My being sanctified in thee before their eyes, O Gog.", "dra": "And thou shalt come upon my people of Israel like a cloud, to cover the earth. Thou shalt be in the latter days, and I will bring thee upon my land: that the nations may know me, when I shall be sanctified in thee, O Gog, before their eyes.", "bbe": "And you will come up against my people Israel, like a cloud covering the land; and it will come about, in the last days, that I will make you come against my land, so that the nations may have knowledge of me when I make myself holy in you, O Gog, before their eyes.", "geneva": "And thou shalt come vp against my people of Israel, as a cloude to couer the land: thou shalt be in the latter dayes, and I will bring thee vpon my lande, that the heathen may knowe mee, when I shalbe sanctified in thee, O Gog, before their eyes.", "wycliffe": "and thou as a cloude schalt stie on my puple Israel, that thou hile the erthe? Thou schalt be in the laste daies, and Y schal brynge thee on my lond, that my folkis wite, whanne Y schal be halewid in thee, thou Gog, bifor the iyen of them.", "rotherham": "Therefore wilt thou come up, against my people Israel, like a cloud covering the land,— In the afterpart of the days, shall it be. that I will suffer thee to enter upon my land, To the end the nations may know me, when I hallow myself in thee before their eyes O Gog!", "darby": "And thou shalt come up against my people Israel as a cloud to cover the land — it shall be at the end of days — and I will bring thee against my land, that the nations may know me, when I shall be hallowed in thee, O Gog, before their eyes.", "twenty": "", "jps": "and thou shalt come up against My people Israel, as a cloud to cover the land; it shall be in the end of days, and I will bring thee against My land, that the nations may know Me, when I shall be sanctified through thee, O Gog, before their eyes.", "acv": "And thou shall come up against my people Israel, as a cloud to cover the land. It shall come to pass in the latter days, that I will bring thee against my land, that the nations may know me, when I shall be sanctified in thee, O Gog, before their eyes.", "anderson": "", "haweis": "", "noyes": "thou shalt come up against my people Israel like a cloud, to cover the land; in the latter days it shall come to pass, that I will bring thee against my land, that the nations may know me, when I shall be sanctified in regard to thee, before their eyes, O Gog!", "webster": "And thou shalt come against my people of Israel, as a cloud to cover the land; it shall be in the latter days, and I will bring thee against my land, that the heathen may know me, when I shall be sanctified in thee, O Gog, before their eyes.", "vulgate": "et ascendes super populum meum Israhel quasi nubes ut operias terram in novissimis diebus eris et adducam te super terram meam ut sciant gentes me cum sanctificatus fuero in te in oculis eorum o Gog;", "brenton": "And thou shalt come up upon my people Israel as a cloud to cover the land; it shall come to pass in the last days, that I will bring thee up upon my land, that all the nations may know me, when I am sanctified in thee before them."}}, {"v": 17, "ref": "38:17", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה הַֽ/אַתָּה ה֨וּא אֲשֶׁר דִּבַּ֜רְתִּי בְּ/יָמִ֣ים קַדְמוֹנִ֗ים בְּ/יַד֙ עֲבָדַ/י֙ נְבִיאֵ֣י יִשְׂרָאֵ֔ל הַֽ/נִּבְּאִ֛ים בַּ/יָּמִ֥ים הָ/הֵ֖ם שָׁנִ֑ים לְ/הָבִ֥יא אֹתְ/ךָ֖ עֲלֵי/הֶֽם", "en": {"kjv": "Thus saith the Lord God; Art thou he of whom I have spoken in old time by my servants the prophets of Israel, which prophesied in those days many years that I would bring thee against them?", "web": "Thus says the Lord Yahweh: Are you he of whom I spoke in old time by my servants the prophets of Israel, who prophesied in those days for years that I would bring you against them?", "bsb": "This is what the Lord GOD says: Are you the one of whom I have spoken in former days through My servants, the prophets of Israel, who in those times prophesied for years that I would bring you against them?", "asv": "Thus saith the Lord Jehovah: Art thou he of whom I spake in old time by my servants the prophets of Israel, that prophesied in those days for many years that I would bring thee against them?", "ylt": "Thus said the Lord Jehovah: Art thou he of whom I spake in former days, By the hand of My servants, prophets of Israel, Who are prophesying in those days--years, To bring thee in against them?", "dra": "Thus saith the Lord God: Thou then art he, of whom I have spoken in the days of old, by my servants the prophets of Israel, who prophesied in the days of those times that I would bring thee upon them.", "bbe": "This is what the Lord has said: You are he of whom I gave them word in earlier times by my servants, the prophets of Israel, who in those days went on saying, year after year, that I would make you come up against them.", "geneva": "Thus saith the Lord God, Art not thou he, of whom I haue spoken in olde time, by ye hand of my seruants the Prophets of Israel which prophecied in those dayes and yeeres, that I woulde bring thee vpon them?", "wycliffe": "The Lord God seith these thingis, Therfor thou art he of whom Y spak in elde daies, in the hond of my seruauntis, profetis of Israel, that profesieden in the daies of tho tymes, that Y schulde bringe thee on hem.", "rotherham": "Thus, saith My Lord, Yahweh, Art thou, he of whom I spake in days aforetime by the hand of my servants the prophets of Israel, who kept on prophesying in those days for years,—That thou shouldest be suffered to come against them?", "darby": "Thus saith the Lord Jehovah: Art thou not he of whom I have spoken in old time through my servants the prophets of Israel, who prophesied in those days, for [many] years, that I would bring thee against them?", "twenty": "", "jps": "Thus saith the L-rd GOD: Art thou he of whom I spoke in old time by My servants the prophets of Israel, that prophesied in those days for many years, that I would bring thee against them?", "acv": "Thus says the lord Jehovah: Are thou he of whom I spoke in old time by my servants the prophets of Israel, who prophesied in those days for many years that I would bring thee against them?", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Art thou not he of whom I spoke in old time by my servants, the prophets of Israel, who prophesied in those days and years, that I would bring thee against them?", "webster": "Thus saith the Lord GOD; [Art] thou he of whom I have spoken in old time by my servants the prophets of Israel, who prophesied in those days [many] years, that I would bring thee against them?", "vulgate": "haec dicit Dominus Deus tu ergo ille es de quo locutus sum in diebus antiquis in manu servorum meorum prophetarum Israhel qui prophetaverunt in diebus illorum temporum ut adducerem te super eos;", "brenton": "Thus saith the Lord God, to Gog; Thou art he concerning whom I spoke in former times, by the hand of my servants the prophets of Israel, in those days and years, that I would bring thee up against them."}}, {"v": 18, "ref": "38:18", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא בְּ/י֨וֹם בּ֥וֹא גוֹג֙ עַל אַדְמַ֣ת יִשְׂרָאֵ֔ל נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה תַּעֲלֶ֥ה חֲמָתִ֖/י בְּ/אַפִּֽ/י", "en": {"kjv": "And it shall come to pass at the same time when Gog shall come against the land of Israel, saith the Lord God, that my fury shall come up in my face.", "web": "It shall happen in that day, when Gog shall come against the land of Israel, says the Lord Yahweh, that my wrath shall come up into my nostrils.", "bsb": "Now on that day when Gog comes against the land of Israel, declares the Lord GOD, My wrath will flare up.", "asv": "And it shall come to pass in that day, when Gog shall come against the land of Israel, saith the Lord Jehovah, that my wrath shall come up into my nostrils.", "ylt": "And it hath come to pass, in that day, In the day of the coming in of Gog against the land of Israel, An affirmation of the Lord Jehovah, Come up doth My fury in My face,", "dra": "And it shall come to pass in that day, in the day of the coming of Gog upon the land of Israel, saith the Lord God, that my indignation shall come up in my wrath.", "bbe": "And it will come about in that day, when Gog comes up against the land of Israel, says the Lord, that my wrath will come up, and my passion and my bitter feeling.", "geneva": "At the same time also whe Gog shall come against the land of Israel, sayth the Lord God, my wrath shall arise in mine anger.", "wycliffe": "And it schal be, in that dai, in the dai of the comyng of Gog on the lond of Israel, seith the Lord God, myn indignacioun schal stie in my strong veniaunce, and in my feruour;", "rotherham": "So then shall it come to pass in that day, In the day when Gog entereth upon the soil of Israel, Declareth My Lord Yahweh, That mine indignation shall come up into my nostrils;", "darby": "And it shall come to pass in that day, in the day when Gog shall come against the land of Israel, saith the Lord Jehovah, [that] my fury shall come up in my face;", "twenty": "", "jps": "And it shall come to pass in that day, when Gog shall come against the land of Israel, saith the L-rd GOD, that My fury shall arise up in My nostrils.", "acv": "And it shall come to pass in that day, when Gog shall come against the land of Israel, says the lord Jehovah, that my wrath shall come up into my nostrils.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day, in the day when Gog shall come against the land of Israel, saith the Lord Jehovah, that my anger shall ascend in fury.", "webster": "And it shall come to pass at the same time when Gog shall come against the land of Israel, saith the Lord GOD, [that] my fury shall come up in my face.", "vulgate": "et erit in die illa in die adventus Gog super terram Israhel ait Dominus Deus ascendet indignatio mea in furore meo;", "brenton": "And it shall come to pass in that day, in the day when Gog shall come against the land of Israel, saith the Lord God,"}}, {"v": 19, "ref": "38:19", "o": "וּ/בְ/קִנְאָתִ֥/י בְ/אֵשׁ עֶבְרָתִ֖/י דִּבַּ֑רְתִּי אִם לֹ֣א בַּ/יּ֣וֹם הַ/ה֗וּא יִֽהְיֶה֙ רַ֣עַשׁ גָּד֔וֹל עַ֖ל אַדְמַ֥ת יִשְׂרָאֵֽל", "en": {"kjv": "For in my jealousy and in the fire of my wrath have I spoken, Surely in that day there shall be a great shaking in the land of Israel;", "web": "For in my jealousy and in the fire of my wrath have I spoken, Surely in that day there shall be a great shaking in the land of Israel;", "bsb": "In My zeal and fiery rage I proclaim that on that day there will be a great earthquake in the land of Israel.", "asv": "For in my jealousy and in the fire of my wrath have I spoken, Surely in that day there shall be a great shaking in the land of Israel;", "ylt": "And in My zeal, in the fire of My wrath, I have spoken: Is there not in that day a great rushing on the land of Israel?", "dra": "And I have spoken in my zeal, and in the fire of my anger, that in that day there shall be a great commotion upon the land of Israel:", "bbe": "For in the fire of my wrath I have said, Truly, in that day there will be a great shaking in the land of Israel;", "geneva": "For in mine indignation and in the fire of my wrath haue I spoken it: surely at that time there shalbe a great shaking in the land of Israel,", "wycliffe": "Y spak in the fier of my wraththe.", "rotherham": "Yea, in my jealousy, in the fire of mine outburst, have I spoken,- Surely in that day, shall there be a great trembling upon the soil of Israel:", "darby": "for in my jealousy, in the fire of my wrath have I spoken, Verily in that day there shall be a great shaking in the land of Israel;", "twenty": "", "jps": "For in My jealousy and in the fire of My wrath have I spoken: Surely in that day there shall be a great shaking in the land of Israel;", "acv": "For I have spoken in my jealousy and in the fire of my wrath. Surely in that day there shall be a great shaking in the land of Israel,", "anderson": "", "haweis": "", "noyes": "For in my jealousy, in the fire of my wrath, have I spoken, Surely in that day there shall be a great shaking in the land of Israel,", "webster": "For in my jealousy [and] in the fire of my wrath have I spoken, Surely in that day there shall be a great shaking in the land of Israel.", "vulgate": "et in zelo meo in igne irae meae locutus sum quia in die illa erit commotio magna super terram Israhel;", "brenton": "that my wrath and my jealousy shall arise, I have spoken in the fire of mine anger, verily in that day there shall be a great shaking in the land of Israel;"}}, {"v": 20, "ref": "38:20", "o": "וְ/רָעֲשׁ֣וּ מִ/פָּנַ֡/י דְּגֵ֣י הַ/יָּם֩ וְ/ע֨וֹף הַ/שָּׁמַ֜יִם וְ/חַיַּ֣ת הַ/שָּׂדֶ֗ה וְ/כָל הָ/רֶ֨מֶשׂ֙ הָ/רֹמֵ֣שׂ עַל הָֽ/אֲדָמָ֔ה וְ/כֹל֙ הָֽ/אָדָ֔ם אֲשֶׁ֖ר עַל פְּנֵ֣י הָ/אֲדָמָ֑ה וְ/נֶהֶרְס֣וּ הֶ/הָרִ֗ים וְ/נָֽפְלוּ֙ הַ/מַּדְרֵג֔וֹת וְ/כָל חוֹמָ֖ה לָ/אָ֥רֶץ תִּפּֽוֹל", "en": {"kjv": "So that the fishes of the sea, and the fowls of the heaven, and the beasts of the field, and all creeping things that creep upon the earth, and all the men that are upon the face of the earth, shall shake at my presence, and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "web": "so that the fish of the sea, and the birds of the sky, and the animals of the field, and all creeping things who creep on the earth, and all the men who are on the surface of the earth, shall shake at my presence, and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "bsb": "The fish of the sea, the birds of the air, the beasts of the field, every creature that crawls upon the ground, and all mankind on the face of the earth will tremble at My presence. The mountains will be thrown down, the cliffs will collapse, and every wall will fall to the ground.", "asv": "so that the fishes of the sea, and the birds of the heavens, and the beasts of the field, and all creeping things that creep upon the earth, and all the men that are upon the face of the earth, shall shake at my presence, and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "ylt": "And rushed from My presence have fishes of the sea, And the fowl of the heavens, And the beast of the field, And every creeping thing that is creeping on the ground, And all men who are on the face of the ground, And thrown down have been the mountains, And fallen have the ascents, And every wall to the earth falleth.", "dra": "So that the fishes of the sea, and the birds of the air, and the beasts of the field, and every creeping thing that creepeth upon the ground, and all men that are upon the face of the earth, shall be moved at my presence: and the mountains shall be thrown down, and the hedges shall fall, and every wall shall fall to the ground.", "bbe": "So that the fish of the sea and the birds of heaven and the beasts of the field and everything moving on the earth, and all the men who are on the face of the earth, will be shaking before me, and the mountains will be overturned and the high places will come down, and every wall will come falling down to the earth.", "geneva": "So that the fishes of the sea, and the foules of the heauen, and the beasts of the field and al that moue and creepe vpon the earth, and al ye men that are vpon the earth, shall tremble at my presence, and the mountaines shalbe ouerthrowen, and the staires shall fall, and euery wall shall fall to the ground.", "wycliffe": "For in that dai schal be grete mouyng on the lond of Israel; and fischis of the see, and beestis of erthe, and briddis of the eir, and ech crepynge beeste which is mouyd on erthe, and alle men that ben on the face of erthe, schulen be mouyd fro my face; and hillis schulen be vndurturned, and heggis schulen falle doun, and ech wal schal falle doun in to erthe.", "rotherham": "Then shall tremble before me The fishes of the sea, and The bird of the heavens and The wild beast of the field, and Every creeping thing that creepeth on the ground, and All the men who are on the face of the ground,— and The mountains, shall be torn asunder, and The steep places, shall sink down, and, Every wall, to the earth, shall be thrown.", "darby": "so that the fish of the sea, and the fowl of the heavens, and the beasts of the field, and all creeping things which creep upon the earth, and all mankind that are upon the face of the earth shall shake at my presence; and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "twenty": "", "jps": "so that the fishes of the sea, and the fowls of the heaven, and the beasts of the field and all creeping things that creep upon the ground, and all the men that are upon the face of the earth, shall shake at My presence, and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "acv": "so that the fishes of the sea, and the birds of the heavens, and the beasts of the field, and all creeping things that creep upon the earth, and all the men who are upon the face of the earth, shall shake at my presence. And the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "anderson": "", "haweis": "", "noyes": "so that the fishes of the sea, and the birds of the heavens, and the beasts of the field; and every creeping thing that creepeth upon the ground, and all the men that are upon the face of the earth, shall shake at my presence; and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.", "webster": "So that the fishes of the sea, and the fowls of the heaven, and the beasts of the field, and all creeping animals that creep upon the earth, and all the men that [are] upon the face of the earth, shall shake at my presence, and the mountains shall be overturned, and the steep places shall fall, and every wall shall fall to the ground.", "vulgate": "et commovebuntur a facie mea pisces maris et volucres caeli et bestiae agri et omne reptile quod movetur super humum cunctique homines qui sunt super faciem terrae et subvertentur montes et cadent sepes et omnis murus in terra corruet;", "brenton": "and the fish of the sea shall quake at the presence of the Lord, and the birds of the sky and the wild beasts of the field, and all the reptiles that creep upon the earth, and all the men that are on the face of the earth; and the mountains shall be rent, and the valleys shall fall, and every wall on the land shall fall."}}, {"v": 21, "ref": "38:21", "o": "וְ/קָרָ֨אתִי עָלָ֤י/ו לְ/כָל הָרַ/י֙ חֶ֔רֶב נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה חֶ֥רֶב אִ֖ישׁ בְּ/אָחִ֥י/ו תִּֽהְיֶֽה", "en": {"kjv": "And I will call for a sword against him throughout all my mountains, saith the Lord God: every man’s sword shall be against his brother.", "web": "I will call for a sword against him to all my mountains, says the Lord Yahweh: every man’s sword shall be against his brother.", "bsb": "And I will summon a sword against Gog on all My mountains, declares the Lord GOD, and every man’s sword will be against his brother.", "asv": "And I will call for a sword against him unto all my mountains, saith the Lord Jehovah: every man’s sword shall be against his brother.", "ylt": "And I have called against him, to all My mountains a sword, An affirmation of the Lord Jehovah, The sword of each is against his brother.", "dra": "And I will call in the sword against him in all my mountains, saith the Lord God: every man's sword shall be pointed against his brother.", "bbe": "And I will send to all my mountains for a sword against him, says the Lord: every man's sword will be against his brother.", "geneva": "For I will call for a sworde against him throughout all my mountaines, saith the Lord God: euery mans sword shalbe against his brother.", "wycliffe": "And Y schal clepe togidere a swerd ayens hym in alle myn hillis, seith the Lord God; the swerd of ech man schal be dressid ayens his brother.", "rotherham": "Then will I call against him, every terror, Declareth My Lord Yahweh, the sword of every man against his brother, shall be;", "darby": "And I will call for a sword against him throughout all my mountains, saith the Lord Jehovah: every man's sword shall be against his brother.", "twenty": "", "jps": "And I will call for a sword against him throughout all my mountains, saith the L-rd GOD; every man's sword shall be against his brother.", "acv": "And I will call for a sword against him to all my mountains, says the lord Jehovah. Every man's sword shall be against his brother.", "anderson": "", "haweis": "", "noyes": "And I will call for a sword against him throughout all my mountains, saith the Lord Jehovah, and they shall all turn their swords against each other,", "webster": "And I will call for a sword against him throughout all my mountains, saith the Lord GOD: every man's sword shall be against his brother.", "vulgate": "et convocabo adversum eum in cunctis montibus meis gladium ait Dominus Deus gladius uniuscuiusque in fratrem suum dirigetur;", "brenton": "And I will summon against it even every fear, saith the Lord: the sword of every man shall be against his brother."}}, {"v": 22, "ref": "38:22", "o": "וְ/נִשְׁפַּטְתִּ֥י אִתּ֖/וֹ בְּ/דֶ֣בֶר וּ/בְ/דָ֑ם וְ/גֶ֣שֶׁם שׁוֹטֵף֩ וְ/אַבְנֵ֨י אֶלְגָּבִ֜ישׁ אֵ֣שׁ וְ/גָפְרִ֗ית אַמְטִ֤יר עָלָי/ו֙ וְ/עַל אֲגַפָּ֔י/ו וְ/עַל עַמִּ֥ים רַבִּ֖ים אֲשֶׁ֥ר אִתּֽ/וֹ", "en": {"kjv": "And I will plead against him with pestilence and with blood; and I will rain upon him, and upon his bands, and upon the many people that are with him, an overflowing rain, and great hailstones, fire, and brimstone.", "web": "With pestilence and with blood will I enter into judgment with him; and I will rain on him, and on his hordes, and on the many peoples who are with him, an overflowing shower, and great hailstones, fire, and sulfur.", "bsb": "I will execute judgment upon him with plague and bloodshed. I will pour out torrents of rain, hailstones, fire, and sulfur on him and on his troops and on the many nations with him.", "asv": "And with pestilence and with blood will I enter into judgment with him; and I will rain upon him, and upon his hordes, and upon the many peoples that are with him, an overflowing shower, and great hailstones, fire, and brimstone.", "ylt": "And I have been judged with him, With pestilence and with blood, And an overflowing rain and hailstones, Fire and brimstone I rain on him, and on his bands, And on many peoples who are with him.", "dra": "And I will judge him with pestilence, and with blood, and with violent rain, and vast hailstones: I will rain fire and brimstone upon him, and upon his army, and upon the many nations that are with him.", "bbe": "And I will take up my cause against him with disease and with blood; and I will send down on him and on his forces and on the peoples who are with him, an overflowing shower and great ice-drops, fire, and burning.", "geneva": "And I will pleade against him with pestilence, and with blood, and I will cause to raine vpon him and vpon his bands, and vpon the great people, that are with him, a sore raine, and hailestones, fire, and brimstone.", "wycliffe": "And thanne Y schal deme hym bi pestilence, and blood, and greet reyn, and bi greet stoonys; Y schal reyn fier and brymstoon on hym, and on his oost, and on many puplis that ben with hym.", "rotherham": "Then will I contend with him by pestilence and by blood,- And an overflowing downpour and hail-stones fire and brimstone, will I rain Upon him, and Upon his hordes, and Upon the many peoples who are with him.", "darby": "And I will enter into judgment with him with pestilence and with blood; and I will rain upon him, and upon his bands, and upon the many peoples that are with him, overflowing rain and great hailstones, fire and brimstone.", "twenty": "", "jps": "And I will plead against him with pestilence and with blood; and I will cause to rain upon him, and upon his bands, and upon the many peoples that are with him, an overflowing shower, and great hailstones, fire, and brimstone.", "acv": "And I will enter into judgment with him with pestilence and with blood. And I will rain upon him, and upon his hordes, and upon the many peoples who are with him, an overflowing shower, and great hailstones, fire, and brimstone.", "anderson": "", "haweis": "", "noyes": "And I will contend against him with pestilence, and with blood; and overflowing showers, and great hailstones, fire and brimstone, will I rain upon him and his hosts, and the many nations that are with him.", "webster": "And I will plead against him with pestilence and with blood; and I will rain upon him, and upon his bands, and upon the many people that [are] with him, an overflowing rain, and great hailstones, fire, and brimstone.", "vulgate": "et iudicabo eum peste et sanguine et imbre vehementi et lapidibus inmensis ignem et sulphur pluam super eum et super exercitum eius et super populos multos qui sunt cum eo;", "brenton": "And I will judge him with pestilence, and blood, and sweeping rain, and hailstones; and I will rain upon him fire and brimstone, and upon all that are with him, and upon many nations with him."}}, {"v": 23, "ref": "38:23", "o": "וְ/הִתְגַּדִּלְתִּי֙ וְ/הִתְקַדִּשְׁתִּ֔י וְ/נ֣וֹדַעְתִּ֔י לְ/עֵינֵ֖י גּוֹיִ֣ם רַבִּ֑ים וְ/יָדְע֖וּ כִּֽי אֲנִ֥י יְהוָֽה", "en": {"kjv": "Thus will I magnify myself, and sanctify myself; and I will be known in the eyes of many nations, and they shall know that I am the Lord.", "web": "I will magnify myself, and sanctify myself, and I will make myself known in the eyes of many nations; and they shall know that I am Yahweh.", "bsb": "I will magnify and sanctify Myself, and will reveal Myself in the sight of many nations. Then they will know that I am the LORD.", "asv": "And I will magnify myself, and sanctify myself, and I will make myself known in the eyes of many nations; and they shall know that I am Jehovah.", "ylt": "And I have magnified Myself, and sanctified Myself, And I have been known before the eyes of many nations, And they have known that I am Jehovah!", "dra": "And I will be magnified, and I will be sanctified: and I will be known in the eyes of many nations and they shall know that I am the Lord.", "bbe": "And I will make my name great and make myself holy, and I will make myself clear to a number of nations; and they will be certain that I am the Lord.", "geneva": "Thus will I be magnified, and sanctified, and knowen in the eyes of many nations, and they shall knowe, that I am the Lord.", "wycliffe": "And Y schal be magnefied, and Y shal be halewid, and Y shal be knowun bifore the iyen of many folkis; and thei schulen wite, that Y am the Lord.", "rotherham": "So will I Magnify myself and Hallow myself, and Make myself known. Before the eyes of many nations,—And they shall know that I, am Yahweh.", "darby": "And I will magnify myself, and sanctify myself, and I will be known in the eyes of many nations, and they shall know that I [am] Jehovah.", "twenty": "", "jps": "Thus will I magnify Myself, and sanctify Myself, and I will make Myself known in the eyes of many nations; and they shall know that I am HaShem.", "acv": "And I will magnify myself, and sanctify myself, and I will make myself known in the eyes of many nations. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus will I show myself in my greatness and glory, and make myself known before the eyes of many nations, and they shall know that I am Jehovah.", "webster": "Thus will I magnify myself, and sanctify myself; and I will be known in the eyes of many nations, and they shall know that I [am] the LORD.", "vulgate": "et magnificabor et sanctificabor et notus ero in oculis gentium multarum et scient quia ego Dominus;", "brenton": "And I will be magnified, and sanctified, and glorified; and I will be known in the presence of many nations, and they shall know that I am the Lord."}}]}, {"c": 39, "verses": [{"v": 1, "ref": "39:1", "o": "וְ/אַתָּ֤ה בֶן אָדָם֙ הִנָּבֵ֣א עַל גּ֔וֹג וְ/אָ֣מַרְתָּ֔ כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה הִנְ/נִ֤י אֵלֶ֨י/ךָ֙ גּ֔וֹג נְשִׂ֕יא רֹ֖אשׁ מֶ֥שֶׁךְ וְ/תֻבָֽל", "en": {"kjv": "Therefore, thou son of man, prophesy against Gog, and say, Thus saith the Lord God; Behold, I am against thee, O Gog, the chief prince of Meshech and Tubal:", "web": "You, son of man, prophesy against Gog, and say, Thus says the Lord Yahweh: Behold, I am against you, Gog, prince of Rosh, Meshech, and Tubal:", "bsb": "“As for you, O son of man, prophesy against Gog and declare that this is what the Lord GOD says: Behold, I am against you, O Gog, chief prince of Meshech and Tubal.", "asv": "And thou, son of man, prophesy against Gog, and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Rosh, Meshech, and Tubal:", "ylt": "And thou, son of man, prophesy concerning Gog, and thou hast said: Thus said the Lord Jehovah: Lo, I am against thee, O Gog, Prince of Rosh, Meshech, and Tubal,", "dra": "And thou, son of man, prophesy against Gog, and say: Thus saith the Lord God: Behold, I come against thee, O Gog, the chief prince of Mosoch and Thubal.", "bbe": "And you, son of man, be a prophet against Gog, and say, These are the words of the Lord: See, I am against you, O Gog, ruler of Rosh, Meshech, and Tubal:", "geneva": "Therefore, thou sonne of man, prophecie against Gog, and say, Thus sayeth the Lord God, Behold, I come against thee, O Gog, ye chiefe prince of Meshech and Tubal.", "wycliffe": "But profesie thou, sone of man, ayens Gog; and thou schalt seie, The Lord God seith these thingis, Lo! Y on thee, thou Gog, prince of the heed of Mosoch and of Tubal.", "rotherham": "Thou therefore son of man. Prophesy against Gog, and thou shalt say, Thus saith My Lord Yahweh: Behold me! against thee O Gog Prince of Rosh, Meshech and Tubal.", "darby": "And thou, son of man, prophesy against Gog, and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Rosh, Meshech, and Tubal;", "twenty": "", "jps": "And thou, son of man, prophesy against Gog, and say: Thus saith the L-rd GOD: Behold, I am against thee, O Gog, chief prince of Meshech and Tubal;", "acv": "And thou, son of man, prophesy against Gog, and say, Thus says the lord Jehovah: Behold, I am against thee, O Gog, ruler of Rosh, Meshech, and Tubal.", "anderson": "", "haweis": "", "noyes": "And do thou, son of man, prophesy against Gog, and say, Thus saith the Lord Jehovah: Behold, I am against thee, O Gog, prince of Resh, Meshech, and Tubal!", "webster": "Therefore, thou son of man, prophesy against Gog, and say, Thus saith the Lord GOD; Behold, I [am] against thee, O Gog, the chief prince of Meshech and Tubal:", "vulgate": "tu autem fili hominis vaticinare adversum Gog et dices haec dicit Dominus Deus ecce ego super te Gog principem capitis Mosoch et Thubal;", "brenton": "And thou, son of man, prophesy against Gog, and say, Thus saith the Lord; Behold, I am against thee, O Gog, Rhos prince of Mesoch and Thobel:"}}, {"v": 2, "ref": "39:2", "o": "וְ/שֹׁבַבְתִּ֨י/ךָ֙ וְ/שִׁשֵּׁאתִ֔י/ךָ וְ/הַעֲלִיתִ֖י/ךָ מִ/יַּרְכְּתֵ֣י צָפ֑וֹן וַ/הֲבִאוֹתִ֖/ךָ עַל הָרֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And I will turn thee back, and leave but the sixth part of thee, and will cause thee to come up from the north parts, and will bring thee upon the mountains of Israel:", "web": "and I will turn you around, and will lead you on, and will cause you to come up from the uttermost parts of the north; and I will bring you on the mountains of Israel;", "bsb": "I will turn you around, drive you along, bring you up from the far north, and send you against the mountains of Israel.", "asv": "and I will turn thee about, and will lead thee on, and will cause thee to come up from the uttermost parts of the north; and I will bring thee upon the mountains of Israel;", "ylt": "And have turned thee back, and enticed thee, And caused thee to come up from the sides of the north, And brought thee in against mountains of Israel,", "dra": "And I will turn thee round, and I will lead thee out, and will make thee go up from the northern parts: and will bring thee upon the mountains of Israel.", "bbe": "And turning you round, I will be your guide, and make you come up from the inmost parts of the north; I will make you come on to the mountains of Israel:", "geneva": "And I will destroy thee and leaue but the sixt part of thee, and will cause thee to come vp from the North partes and will bring thee vpon the mountaines of Israel:", "wycliffe": "And Y schal lede thee aboute, and Y schal disseyue thee, and Y schal make thee to stie fro the sidis of the north, and Y schal brynge thee on the hillis of Israel.", "rotherham": "Therefore will I turn thee about and lead thee on, and cause thee to come up out of the remote parts of the North,- And will bring thee in upon the mountains of Israel;", "darby": "and I will turn thee back, and lead thee, and will cause thee to come up from the uttermost north, and will bring thee upon the mountains of Israel.", "twenty": "", "jps": "and I will turn thee about and lead thee on, and will cause thee to come up from the uttermost parts of the north; and I will bring thee upon the mountains of Israel;", "acv": "And I will turn thee about, and will lead thee on, and will cause thee to come up from the outermost parts of the north, and I will bring thee upon the mountains of Israel.", "anderson": "", "haweis": "", "noyes": "I will turn thee, and lead thee about, and cause thee to come up from the regions of the North. and bring thee upon the mountains of Israel.", "webster": "And I will turn thee back, and leave but the sixth part of thee, and will cause thee to come from the north parts, and will bring thee upon the mountains of Israel:", "vulgate": "et circumagam te et seducam te et ascendere faciam de lateribus aquilonis et adducam te super montes Israhel;", "brenton": "and I will assemble thee, and guide thee, and raise thee up on the extremity of the north, and I will bring thee up upon the mountains of Israel."}}, {"v": 3, "ref": "39:3", "o": "וְ/הִכֵּיתִ֥י קַשְׁתְּ/ךָ֖ מִ/יַּ֣ד שְׂמֹאולֶ֑/ךָ וְ/חִצֶּ֕י/ךָ מִ/יַּ֥ד יְמִינְ/ךָ֖ אַפִּֽיל", "en": {"kjv": "And I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.", "web": "and I will strike your bow out of your left hand, and will cause your arrows to fall out of your right hand.", "bsb": "Then I will strike the bow from your left hand and dash down the arrows from your right hand.", "asv": "and I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.", "ylt": "And have smitten thy bow out of thy left hand, Yea, thine arrows out of thy right I cause to fall.", "dra": "And I will break thy bow in thy left hand, and I will cause thy arrows to fall out of thy right hand.", "bbe": "And with a blow I will send your bow out of your left hand and your arrows falling from your right hand.", "geneva": "And I will smite thy bowe out of thy left hand, and I will cause thine arrowes to fall out of thy right hand.", "wycliffe": "And Y schal smyte thi bouwe in thi left hond, and Y schal caste doun thin arowis fro thi riyt hond.", "rotherham": "And I will smite thy bow out of thy left hand,- And thine arrows—out of thy right hand, will I cause to fall.", "darby": "And I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.", "twenty": "", "jps": "and I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.", "acv": "And I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.", "anderson": "", "haweis": "", "noyes": "And I will smite thy bow out of thy left hand, and cause thine arrows to fall out of thy right hand.", "webster": "And I will strike thy bow out of thy left hand, and I will cause thy arrows to fall from thy right hand.", "vulgate": "et percutiam arcum tuum in manu sinistra tua et sagittas tuas de manu dextera tua deiciam;", "brenton": "And I will destroy the bow out of thy left hand, and thine arrows out of thy right hand, and I will cast thee down on the mountains of Israel;"}}, {"v": 4, "ref": "39:4", "o": "עַל הָרֵ֨י יִשְׂרָאֵ֜ל תִּפּ֗וֹל אַתָּה֙ וְ/כָל אֲגַפֶּ֔י/ךָ וְ/עַמִּ֖ים אֲשֶׁ֣ר אִתָּ֑/ךְ לְ/עֵ֨יט צִפּ֧וֹר כָּל כָּנָ֛ף וְ/חַיַּ֥ת הַ/שָּׂדֶ֖ה נְתַתִּ֥י/ךָ לְ/אָכְלָֽה", "en": {"kjv": "Thou shalt fall upon the mountains of Israel, thou, and all thy bands, and the people that is with thee: I will give thee unto the ravenous birds of every sort, and to the beasts of the field to be devoured.", "web": "You shall fall on the mountains of Israel, you, and all your hordes, and the peoples who are with you: I will give you to the ravenous birds of every sort, and to the animals of the field to be devoured.", "bsb": "On the mountains of Israel you will fall—you and all your troops and the nations with you. I will give you as food to every kind of ravenous bird and wild beast.", "asv": "Thou shalt fall upon the mountains of Israel, thou, and all thy hordes, and the peoples that are with thee: I will give thee unto the ravenous birds of every sort, and to the beasts of the field to be devoured.", "ylt": "On mountains of Israel thou fallest, Thou, and all thy bands, and the peoples who are with thee, To ravenous fowl--a bird of every wing, And to a beast of the field, I have given thee for food.", "dra": "Thou shalt fall upon the mountains of Israel, thou and all thy bands, and thy nations that are with thee: I have given thee to the wild beasts, to the birds, and to every fowl, and to the beasts of the earth to be devoured.", "bbe": "On the mountains of Israel you will come down, you and all your forces and the peoples who are with you: I will give you to cruel birds of every sort and to the beasts of the field to be their food.", "geneva": "Thou shalt fal vpon the mountaines of Israel, and all thy bands and the people, that is with thee: for I will giue thee vnto the birdes and to euery feathered foule and beast of the fielde to be deuoured.", "wycliffe": "Thou schalt falle doun on the hillis of Israel, thou, and alle thi cumpenyes, and puplis that ben with thee; Y yaf thee for to be deuourid to wielde beestis, to briddis, and to ech volatil, and to the beestis of erthe.", "rotherham": "Upon the mountains of Israel, shalt thou fall, Thou and all thy hordes, and the peoples who are with thee,— To birds of prey of every wing. and the wild beast of the field, will I give thee for food:", "darby": "Thou shalt fall upon the mountains of Israel, thou, and all thy bands, and the peoples that are with thee: I have given thee to be meat for the birds of prey of every wing, and to the beasts of the field.", "twenty": "", "jps": "Thou shalt fall upon the mountains of Israel, thou, and all thy bands, and the peoples that are with thee; I will give thee unto the ravenous birds of every sort and to the beasts of the field, to be devoured.", "acv": "Thou shall fall upon the mountains of Israel, thou, and all thy hordes, and the peoples who are with thee. I will give thee to the ravenous birds of every sort, and to the beasts of the field to be devoured.", "anderson": "", "haweis": "", "noyes": "Thou shalt fall upon the mountains of Israel, thou and all thy hosts, and the nations that are with thee. To the ravenous birds of every wing, and to the beasts of the forest, give I thee to be devoured.", "webster": "Thou shalt fall upon the mountains of Israel, thou, and all thy bands, and the people that [are] with thee: I will give thee to the ravenous birds of every sort, and [to] the beasts of the field to be devoured.", "vulgate": "super montes Israhel cades tu et omnia agmina tua et populi qui sunt tecum feris avibus omnique volatili et bestiis terrae dedi te devorandum;", "brenton": "and thou and all that belong to thee shall fall, and the nations that are with thee shall be given to multitudes of birds, even to every fowl, and I have given thee to all the wild beasts of the field to be devoured."}}, {"v": 5, "ref": "39:5", "o": "עַל פְּנֵ֥י הַ/שָּׂדֶ֖ה תִּפּ֑וֹל כִּ֚י אֲנִ֣י דִבַּ֔רְתִּי נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thou shalt fall upon the open field: for I have spoken it, saith the Lord God.", "web": "You shall fall on the open field; for I have spoken it, says the Lord Yahweh.", "bsb": "You will fall in the open field, for I have spoken, declares the Lord GOD.", "asv": "Thou shalt fall upon the open field; for I have spoken it, saith the Lord Jehovah.", "ylt": "On the face of the field thou fallest, for I have spoken, An affirmation of the Lord Jehovah.", "dra": "Thou shalt fall upon the face of the field: for I have spoken it, saith the Lord God.", "bbe": "You will come down in the open field: for I have said it, says the Lord.", "geneva": "Thou shalt fall vpon the open fielde: for I haue spoken it, sayth the Lord God.", "wycliffe": "Thou schalt falle doun on the face of the feeld; for Y the Lord haue spoke, seith the Lord God.", "rotherham": "Upon the, face of the field, shalt thou fall,- For I, have spoken, Declareth My Lord Yahweh.", "darby": "Thou shalt fall on the open field; for I have spoken [it], saith the Lord Jehovah.", "twenty": "", "jps": "Thou shalt fall upon the open field; for I have spoken it, saith the L-rd GOD.", "acv": "Thou shall fall upon the open field, for I have spoken it, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thou shalt fall upon the open field; for I have spoken it, saith the Lord Jehovah.", "webster": "Thou shalt fall upon the open field: for I have spoken [it], saith the Lord GOD.", "vulgate": "super faciem agri cades quia ego locutus sum ait Dominus Deus;", "brenton": "Thou shalt fall on the face of the field: for I have spoken it, saith the Lord."}}, {"v": 6, "ref": "39:6", "o": "וְ/שִׁלַּחְתִּי אֵ֣שׁ בְּ/מָג֔וֹג וּ/בְ/יֹשְׁבֵ֥י הָ/אִיִּ֖ים לָ/בֶ֑טַח וְ/יָדְע֖וּ כִּי אֲנִ֥י יְהוָֽה", "en": {"kjv": "And I will send a fire on Magog, and among them that dwell carelessly in the isles: and they shall know that I am the Lord.", "web": "I will send a fire on Magog, and on those who dwell securely in the islands; and they shall know that I am Yahweh.", "bsb": "I will send fire on Magog and on those who dwell securely in the coastlands, and they will know that I am the LORD.", "asv": "And I will send a fire on Magog, and on them that dwell securely in the isles; and they shall know that I am Jehovah.", "ylt": "And I have sent a fire against Magog, And against the confident inhabitants of the isles, And they have known that I am Jehovah.", "dra": "And I will send a fire on Magog, and on them that dwell confidently in the islands: and they shall know that I am the Lord.", "bbe": "And I will send a fire on Magog, and on those who are living in the sea-lands without fear: and they will be certain that I am the Lord.", "geneva": "And I will sende a fire on Magog, and among them that dwell safely in the yles, and they shall knowe that I am the Lord.", "wycliffe": "And Y schal sende fier in Magog, and in hem that dwellen tristili in ilis; and thei schulen wite, that Y am the Lord God of Israel.", "rotherham": "And I will send a fire into Magog, And among them who are dwelling in the Coastlands securely,— So shalt thou know that I am Yahweh.", "darby": "And I will send a fire on Magog, and among them that dwell at ease in the isles: and they shall know that I [am] Jehovah.", "twenty": "", "jps": "And I will send a fire on Magog, and on them that dwell safely in the isles; and they shall know that I am HaShem.", "acv": "And I will send a fire on Magog, and on those who dwell securely in the isles. And they shall know that I am Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will send a fire upon Magog, and upon them that dwell in security in the sea-coasts; and they shall know that I am Jehovah.", "webster": "And I will send a fire on Magog, and among them that dwell carelessly in the isles: and they shall know that I [am] the LORD.", "vulgate": "et emittam ignem in Magog et in his qui habitant in insulis confidenter et scient quia ego Dominus;", "brenton": "And I will send a fire upon Gog, and the islands shall be securely inhabited: and they shall know that I am the Lord."}}, {"v": 7, "ref": "39:7", "o": "וְ/אֶת שֵׁ֨ם קָדְשִׁ֜/י אוֹדִ֗יעַ בְּ/תוֹךְ֙ עַמִּ֣/י יִשְׂרָאֵ֔ל וְ/לֹֽא אַחֵ֥ל אֶת שֵׁם קָדְשִׁ֖/י ע֑וֹד וְ/יָדְע֤וּ הַ/גּוֹיִם֙ כִּי אֲנִ֣י יְהוָ֔ה קָד֖וֹשׁ בְּ/יִשְׂרָאֵֽל", "en": {"kjv": "So will I make my holy name known in the midst of my people Israel; and I will not let them pollute my holy name any more: and the heathen shall know that I am the Lord, the Holy One in Israel.", "web": "My holy name will I make known in the midst of my people Israel; neither will I allow my holy name to be profaned any more: and the nations shall know that I am Yahweh, the Holy One in Israel.", "bsb": "So I will make My holy name known among My people Israel and will no longer allow it to be profaned. Then the nations will know that I am the LORD, the Holy One in Israel.", "asv": "And my holy name will I make known in the midst of my people Israel; neither will I suffer my holy name to be profaned any more: and the nations shall know that I am Jehovah, the Holy One in Israel.", "ylt": "And My holy name I make known in the midst of My people Israel, And I pollute not My holy name any more, And known have the nations that I, Jehovah, the Holy One, am in Israel.", "dra": "And I will make my holy name known in the midst of my people Israel, and my holy name shall be profaned no more: and the Gentiles shall know that I am the Lord, the Holy One of Israel.", "bbe": "And I will make clear my holy name among my people Israel; I will no longer let my holy name be made unclean: and the nations will be certain that I am the Lord, the Holy One in Israel.", "geneva": "So will I make mine holy Name knowen in the middes of my people Israel, and I will not suffer them to pollute mine holy Name any more, and the heathen shall knowe that I am the Lord, the holy one of Israel.", "wycliffe": "And Y schal make myn hooli name knowun in the myddis of my puple Israel, and Y schal no more defoule myn hooli name; and hethene men schulen wite, that Y am the Lord God, the hooli of Israel.", "rotherham": "And my holy Name, will I make known in the midst of my people Israel, And will not suffer my holy Name to be profaned any more,— So shall the nations know that, I am Yahweh, Holy in Israel.", "darby": "And my holy name will I make known in the midst of my people Israel; and I will not suffer my holy name to be profaned any more: and the nations shall know that I [am] Jehovah, the Holy One in Israel.", "twenty": "", "jps": "And My holy name will I make known in the midst of My people Israel; neither will I suffer My holy name to be profaned any more; and the nations shall know that I am HaShem, the Holy One in Israel.", "acv": "And I will make my holy name known in the midst of my people Israel, nor will I allow my holy name to be profaned any more. And the nations shall know that I am Jehovah, the Holy One in Israel.", "anderson": "", "haweis": "", "noyes": "So will I make my holy name known in the midst of my people Israel, and I will not suffer my holy name to be polluted any more; and the nations shall", "webster": "So will I make my holy name known in the midst of my people Israel; and I will not [let them] profane my holy name any more: and the heathen shall know that I [am] the LORD, the Holy One in Israel.", "vulgate": "et nomen sanctum meum notum faciam in medio populi mei Israhel et non polluam nomen sanctum meum amplius et scient gentes quia ego Dominus Sanctus Israhel;", "brenton": "And my holy name shall be known in the midst of my people Israel; and my holy name shall no more be profaned: and the nations shall know that I am the Lord, the Holy One in Israel."}}, {"v": 8, "ref": "39:8", "o": "הִנֵּ֤ה בָאָה֙ וְ/נִֽהְיָ֔תָה נְאֻ֖ם אֲדֹנָ֣/י יְהוִ֑ה ה֥וּא הַ/יּ֖וֹם אֲשֶׁ֥ר דִּבַּֽרְתִּי", "en": {"kjv": "Behold, it is come, and it is done, saith the Lord God; this is the day whereof I have spoken.", "web": "Behold, it comes, and it shall be done, says the Lord Yahweh; this is the day about which I have spoken.", "bsb": "Yes, it is coming, and it will surely happen, declares the Lord GOD. This is the day of which I have spoken.", "asv": "Behold, it cometh, and it shall be done, saith the Lord Jehovah; this is the day whereof I have spoken.", "ylt": "Lo, it hath come, and it hath been done, An affirmation of the Lord Jehovah, It is the day of which I spake.", "dra": "Behold it cometh, and it is done, saith the Lord God: this is the day whereof I have spoken.", "bbe": "See, it is coming and it will be done, says the Lord; this is the day of which I have given word.", "geneva": "Beholde, it is come, and it is done, sayeth the Lord God: and this is the day whereof I haue spoken.", "wycliffe": "Lo! it cometh, and it is don, seith the Lord God.", "rotherham": "Lo! it is coming, and shall be brought to pass, Declareth My Lord. Yahweh,-the same, is the day whereof I had spoken.", "darby": "Behold, it cometh, and shall be done, saith the Lord Jehovah. This is the day whereof I have spoken.", "twenty": "", "jps": "Behold, it cometh, and it shall be done, saith the L-rd GOD; This is the day whereof I have spoken.", "acv": "Behold, it comes, and it shall be done, says the lord Jehovah. This is the day of which I have spoken.", "anderson": "", "haweis": "", "noyes": "know that I am Jehovah, the Holy One of Israel. Behold it cometh, and shall be done, saith the Lord Jehovah. This is the day of which I spake.", "webster": "Behold, it is come, and it is done, saith the Lord GOD; this [is] the day of which I have spoken.", "vulgate": "ecce venit et factum est ait Dominus Deus haec est dies de qua locutus sum;", "brenton": "Behold it is come, and thou shalt know that it shall be, saith the Lord God; this is the day concerning which I have spoken."}}, {"v": 9, "ref": "39:9", "o": "וְֽ/יָצְא֞וּ יֹשְׁבֵ֣י עָרֵ֣י יִשְׂרָאֵ֗ל וּ/בִעֲר֡וּ וְ֠/הִשִּׂיקוּ בְּ/נֶ֨שֶׁק וּ/מָגֵ֤ן וְ/צִנָּה֙ בְּ/קֶ֣שֶׁת וּ/בְ/חִצִּ֔ים וּ/בְ/מַקֵּ֥ל יָ֖ד וּ/בְ/רֹ֑מַח וּ/בִעֲר֥וּ בָ/הֶ֛ם אֵ֖שׁ שֶׁ֥בַע שָׁנִֽים", "en": {"kjv": "And they that dwell in the cities of Israel shall go forth, and shall set on fire and burn the weapons, both the shields and the bucklers, the bows and the arrows, and the handstaves, and the spears, and they shall burn them with fire seven years:", "web": "Those who dwell in the cities of Israel shall go out, and shall make fires of the weapons and burn them, both the shields and the bucklers, the bows and the arrows, and the war clubs, and the spears, and they shall make fires of them seven years;", "bsb": "Then those who dwell in the cities of Israel will go out, kindle fires, and burn up the weapons—the bucklers and shields, the bows and arrows, the clubs and spears. For seven years they will use them for fuel.", "asv": "And they that dwell in the cities of Israel shall go forth, and shall make fires of the weapons and burn them, both the shields and the bucklers, the bows and the arrows, and the handstaves, and the spears, and they shall make fires of them seven years;", "ylt": "And gone out have the inhabitants of cities of Israel, And they have burned and kindled a fire , With armour, and shield, and buckler, With bow, and with arrows, And with hand-staves, and with javelins, And they have caused a fire to burn with them seven years,", "dra": "And the inhabitants shall go forth of the cities of Israel, and shall set on fire and burn the weapons, the shields, and the spears, the bows and the arrows, and the handstaves and the pikes: and they shall burn them with fire seven years.", "bbe": "And those who are living in the towns of Israel will go out and make fires of the instruments of war, burning the body-covers and the breastplates, the bows and the arrows and the sticks and the spears, and for seven years they will make fires of them:", "geneva": "And they that dwell in the cities of Israel, shall goe forth, and shall burne and set fire vpon the weapons, and on the shieldes, and bucklers, vpon the bowes, and vpon the arrowes, and vpon the staues in their handes, and vpon the speares, and they shall burne them with fire seuen yeeres.", "wycliffe": "This is the day of which Y spak. And dwelleris schulen go out of the citees of Israel, and thei schulen set a fier, and schulen brenne armuris, scheeld and spere, bouwe and arowis, and stauys of hond, and schaftis with out irun; and thei schulen brenne tho in fier bi seuene yeer.", "rotherham": "Then shall go forth the dwellers of the cities of Israel and shall make fires of the weapons and burn them, Both buckler and shield, bow and arrows, and handstaff and spear,- And shall make fires of them seven years;", "darby": "And they that dwell in the cities of Israel shall go forth, and shall kindle fire, and burn weapons, and shields, and targets, bows, and arrows, and hand-staves, and spears: and they shall make fires with them seven years.", "twenty": "", "jps": "And they that dwell in the cities of Israel shall go forth, and shall make fires of the weapons and use them as fuel, both the shields and the bucklers, the bows and the arrows, and the hand-staves, and the spears, and they shall make fires of them seven years;", "acv": "And those who dwell in the cities of Israel shall go forth, and shall make fires of the weapons and burn them, both the shields and the bucklers, the bows and the arrows, and the hand staves, and the spears. And they shall make fires of them seven years,", "anderson": "", "haweis": "", "noyes": "Then shall the inhabitants of the cities of Israel go forth, and set on fire and burn the weapons, the shields and the bucklers, the bows and the arrows, the hand-staves and the spears, and they shall make fires of them seven years.", "webster": "And they that dwell in the cities of Israel shall go forth, and shall set on fire and burn the weapons, both the shields and the bucklers, the bows and the arrows, and the handstaffs, and the spears, and they shall burn them with fire seven years:", "vulgate": "et egredientur habitatores de civitatibus Israhel et succendent et conburent arma clypeum et hastas arcum et sagittas et baculos manus et contos et succendent ea igne septem annis;", "brenton": "And they that inhabit the cities of Israel shall come forth, and make a fire with the arms, the shields and the spears, and bows and arrows, and hand-staves, and lances, and they shall keep fire burning with them for seven years:"}}, {"v": 10, "ref": "39:10", "o": "וְ/לֹֽא יִשְׂא֨וּ עֵצִ֜ים מִן הַ/שָּׂדֶ֗ה וְ/לֹ֤א יַחְטְבוּ֙ מִן הַ/יְּעָרִ֔ים כִּ֥י בַ/נֶּ֖שֶׁק יְבַֽעֲרוּ אֵ֑שׁ וְ/שָׁלְל֣וּ אֶת שֹׁלְלֵי/הֶ֗ם וּ/בָֽזְזוּ֙ אֶת בֹּ֣זְזֵי/הֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "So that they shall take no wood out of the field, neither cut down any out of the forests; for they shall burn the weapons with fire: and they shall spoil those that spoiled them, and rob those that robbed them, saith the Lord God.", "web": "so that they shall take no wood out of the field, neither cut down any out of the forests; for they shall make fires of the weapons; and they shall plunder those who plundered them, and rob those who robbed them, says the Lord Yahweh.", "bsb": "They will not gather wood from the countryside or cut it from the forests, for they will use the weapons for fuel. They will loot those who looted them and plunder those who plundered them, declares the Lord GOD.", "asv": "so that they shall take no wood out of the field, neither cut down any out of the forests; for they shall make fires of the weapons; and they shall plunder those that plundered them, and rob those that robbed them, saith the Lord Jehovah.", "ylt": "And they do not take wood out of the field, Nor do they hew out of the forests, For with armour they cause the fire to burn, And they have spoiled their spoilers, And they have plundered their plunderers, An affirmation of the Lord Jehovah.", "dra": "And they shall not bring wood out of the countries, nor cut down out of the forests: for they shall burn the weapons with fire, and shall make a prey of them to whom they had been a prey, and they shall rob those that robbed them, saith the Lord God.", "bbe": "And they will take no wood out of the field or have any cut down in the woods; for they will make their fires of the instruments of war: and they will take by force the property of those who took their property, and go off with the goods of those who took their goods, says the Lord.", "geneva": "So that they shall bring no wood out of the fielde, neither cut downe any out of the forestes: for they shall burne the weapons with fire, and they shall robbe those that robbed them, and spoyle those that spoyled them, sayeth the Lord God.", "wycliffe": "And thei schulen not bere trees of cuntries, nether schulen kitte doun of forestis, for thei schulen brenne armuris bi fier; and thei schulen take preies of hem, to whiche thei weren preies, and thei schulen rauysche her wasteris, seith the Lord God.", "rotherham": "And they shall not take wood out of the field Neither shall they cut down out of the forests,- For of the armour, shall they make fires,- So shall they spoil those who spoiled them And prey on those who preyed on them, Declareth My Lord Yahweh.", "darby": "And no wood shall be taken out of the field, neither cut down out of the forests; for they shall make fire with the weapons; and they shall spoil those that spoiled them, and plunder those that plundered them, saith the Lord Jehovah.", "twenty": "", "jps": "so that they shall take no wood out of the field, neither cut down any out of the forests, for they shall make fires of the weapons; and they shall spoil those that spoiled them, and rob those that robbed them, saith the L-rd GOD.", "acv": "so that they shall take no wood out of the field, nor cut down any out of the forests, for they shall make fires of the weapons. And they shall plunder those who plundered them, and rob those who robbed them, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "They shall take no wood from the field, neither shall they cut down any from the forests; for they shall make their fires of the weapons. And they shall spoil those that spoiled them, and plunder those that plundered them, saith the Lord Jehovah.", "webster": "So that they shall take no wood out of the field, neither cut down [any] out of the forests; for they shall burn the weapons with fire: and they shall lay waste those that wasted them, and rob those that robbed them, saith the Lord GOD.", "vulgate": "et non portabunt ligna de regionibus neque succident de saltibus quoniam arma succendent igne et depraedabuntur eos quibus praedae fuerant et diripient vastatores suos ait Dominus Deus;", "brenton": "and they shall not take any wood out of the field, neither shall they cut any out of the forests, but they shall burn the weapons with fire: and they shall plunder those that plundered them, and spoil those that spoiled them, saith the Lord."}}, {"v": 11, "ref": "39:11", "o": "וְ/הָיָ֣ה בַ/יּ֣וֹם הַ/ה֡וּא אֶתֵּ֣ן לְ/גוֹג֩ מְקֽוֹם שָׁ֨ם קֶ֜בֶר בְּ/יִשְׂרָאֵ֗ל גֵּ֤י הָ/עֹֽבְרִים֙ קִדְמַ֣ת הַ/יָּ֔ם וְ/חֹסֶ֥מֶת הִ֖יא אֶת הָ/עֹֽבְרִ֑ים וְ/קָ֣בְרוּ שָׁ֗ם אֶת גּוֹג֙ וְ/אֶת כָּל הֲמוֹנֹ֔/ה וְ/קָ֣רְא֔וּ גֵּ֖יא הֲמ֥וֹן גּֽוֹג", "en": {"kjv": "And it shall come to pass in that day, that I will give unto Gog a place there of graves in Israel, the valley of the passengers on the east of the sea: and it shall stop the noses of the passengers: and there shall they bury Gog and all his multitude: and they shall call it The valley of Hamon–gog.", "web": "It shall happen in that day, that I will give to Gog a place for burial in Israel, the valley of those who pass through on the east of the sea; and it shall stop those who pass through: and there shall they bury Gog and all his multitude; and they shall call it The valley of Hamon Gog.", "bsb": "And on that day I will give Gog a burial place in Israel, the Valley of the Travelers, east of the Sea. It will block those who travel through, because Gog and all his hordes will be buried there. So it will be called the Valley of Hamon-gog.", "asv": "And it shall come to pass in that day, that I will give unto Gog a place for burial in Israel, the valley of them that pass through on the east of the sea; and it shall stop them that pass through: and there shall they bury Gog and all his multitude; and they shall call it The valley of Hamon-gog.", "ylt": "And it hath come to pass, in that day, I give to Gog a place there--a grave in Israel, the valley of those passing by, east of the sea, and it is stopping those passing by, and they have buried there Gog, and all his multitude, and have cried, O valley of the multitude of Gog!", "dra": "And it shall come to pass in that day, that I will give Gog a noted place for a sepulchre in Israel: the valley of the passengers on the east of the sea, which shall cause astonishment in them that pass by: and there shall they bury Gog, and all his multitude, and it shall be called the valley of the multitude of Gog.", "bbe": "And it will come about in those days, that I will give to Gog a last resting-place there in Israel, in the valley of Abarim on the east of the sea: and those who go through will be stopped: and there Gog and all his people will be put to rest, and the place will be named, The valley of Hamon-gog.", "geneva": "And at the same time will I giue vnto Gog a place there for burial in Israel, euen the valley whereby men go towarde the East part of the sea: and it shall cause them that passe by, to stoppe their noses, and there shall they bury Gog with all his multitude: and they shall call it the valley of Hamon-Gog.", "wycliffe": "And it schal be in that dai, Y schal yyue to Gog a named place, a sepulcre in Israel, the valei of weigoeris at the eest of the see, that schal make hem that passen forth for to wondre; and thei schulen birie there Gog, and al the multitude of hym, and it schal be clepid the valei of the multitude of Gog.", "rotherham": "And it shall come to pass in that day that I will give to Gog a place of memorial for burial in Israel even the valley of them that pass through east of the sea, And it shall be enough to keep back them who would pass through,- and they shall bury there Gog and all his multitude, and shall call it Ge-hamon-gog. [That is \"The valley of the multitude of Gog.\"]", "darby": "And it shall come to pass in that day, [that] I will give unto Gog a place there for burial in Israel, the valley of the passers-by to the east of the sea; and it shall stop [the way] of the passers-by; and there shall they bury Gog and all the multitude; and they shall call it, Valley of Hamon-Gog.", "twenty": "", "jps": "And it shall come to pass in that day, that I will give unto Gog a place fit for burial in Israel, the valley of them that pass through on the east of the sea; and it shall stop them that pass through; and there shall they bury Gog and all his multitude; and they shall call it the valley of Hamon-gog.", "acv": "And it shall come to pass in that day, that I will give to Gog a place for burial in Israel: the valley of those who pass through on the east of the sea. And it shall stop those who pass through, and they shall bury Gog and all his multitude there. And they shall call it The valley of Hamon-gog.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day, that I will give to Gog a place there, a grave in Israel, the valley of the passengers on the east of the sea; and it shall stop the way of passengers. There shall they bury Gog and all his multitude, and they shall call it \"The valley of the multitude of Gog.\"", "webster": "And it shall come to pass in that day, [that] I will give to Gog a place there of graves in Israel, the valley of the passengers on the east of the sea: and it shall stop the [noses] of the passengers: and there shall they bury Gog and all his multitude: and they shall call [it] The valley of Hamon-gog.", "vulgate": "et erit in die illa dabo Gog locum nominatum sepulchrum in Israhel vallem Viatorum ad orientem maris quae obstupescere facit praetereuntes et sepelient ibi Gog et omnem multitudinem eius et vocabitur vallis Multitudinis Gog;", "brenton": "And it shall come to pass that in that day I will give to Gog a place of renown, a tomb in Israel, the burial-place of them that approach the sea: and they shall build round about the outlet of the valley, and there they shall bury Gog and all his multitude: and the place shall then be called the burial-place of Gog."}}, {"v": 12, "ref": "39:12", "o": "וּ/קְבָרוּ/ם֙ בֵּ֣ית יִשְׂרָאֵ֔ל לְמַ֖עַן טַהֵ֣ר אֶת הָ/אָ֑רֶץ שִׁבְעָ֖ה חֳדָשִֽׁים", "en": {"kjv": "And seven months shall the house of Israel be burying of them, that they may cleanse the land.", "web": "Seven months shall the house of Israel be burying them, that they may cleanse the land.", "bsb": "For seven months the house of Israel will be burying them in order to cleanse the land.", "asv": "And seven months shall the house of Israel be burying them, that they may cleanse the land.", "ylt": "And the house of Israel have buried them--in order to cleanse the land--seven months.", "dra": "And the house of Israel shall bury them for seven months to cleanse the land.", "bbe": "And the children of Israel will be seven months putting them in the earth, so as to make the land clean.", "geneva": "And seuen moneths long shall the house of Israel be burying of the, that they may clense the land.", "wycliffe": "And the hous of Israel schulen birie hem, that thei clense the lond in seuene monethis.", "rotherham": "So shall the house of Israel bury them (that they may cleanse the land) —seven months;", "darby": "And seven months shall the house of Israel be burying them, that they may cleanse the land;", "twenty": "", "jps": "And seven months shall the house of Israel be burying them, that they may cleanse the land.", "acv": "And the house of Israel shall be burying them seven months, that they may cleanse the land.", "anderson": "", "haweis": "", "noyes": "And seven months shall the house of Israel be burying them, that they may cleanse the land.", "webster": "And seven months shall the house of Israel be in burying them, that they may cleanse the land.", "vulgate": "et sepelient eos domus Israhel ut mundent terram septem mensibus;", "brenton": "And the house of Israel shall bury them, that the land may be cleansed in the space of seven months."}}, {"v": 13, "ref": "39:13", "o": "וְ/קָֽבְרוּ֙ כָּל עַ֣ם הָ/אָ֔רֶץ וְ/הָיָ֥ה לָ/הֶ֖ם לְ/שֵׁ֑ם י֚וֹם הִכָּ֣בְדִ֔/י נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Yea, all the people of the land shall bury them; and it shall be to them a renown the day that I shall be glorified, saith the Lord God.", "web": "Yes, all the people of the land shall bury them; and it shall be to them a renown in the day that I shall be glorified, says the Lord Yahweh.", "bsb": "All the people of the land will bury them, and it will bring them renown on the day I display My glory, declares the Lord GOD.", "asv": "Yea, all the people of the land shall bury them; and it shall be to them a renown in the day that I shall be glorified, saith the Lord Jehovah.", "ylt": "Yea, all the people of the land have buried them, and it hath been to them for a name--the day of My being honoured--an affirmation of the Lord Jehovah.", "dra": "And all the people of the land shall bury him, and it shall be unto them a noted day, wherein I was glorified, saith the Lord God.", "bbe": "And all the people of the land will put them in the earth; and it will be to their honour in the day when I let my glory be seen, says the Lord.", "geneva": "Yea, all the people of the lande shall burie them, and they shall haue a name when I shall be glorified, saith the Lord God.", "wycliffe": "Forsothe al the puple of the lond schal byrie hym, and it schal be a named dai to hem, in which Y am glorified, seith the Lord God.", "rotherham": "Yea all the people of the land, shall bury, and it shall become to them a memorial,—the day that I get myself glory, Declareth My Lord Yahweh.", "darby": "and all the people of the land shall bury [them]; and it shall be to them for renown in the day that I shall be glorified, saith the Lord Jehovah.", "twenty": "", "jps": "Yea, all the people of the land shall bury them, and it shall be to them a renown; in the day that I shall be glorified, saith the L-rd GOD.", "acv": "Yea, all the people of the land shall bury them, and it shall be to them a renown in the day that I shall be glorified, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Yea, all the people of the land shall bury them; and it shall be renown to them, in the day when I shall be glorified, saith the Lord Jehovah.", "webster": "Yes, all the people of the land shall bury [them]: and it shall be to them a renown in the day that I shall be glorified, saith the Lord GOD.", "vulgate": "sepeliet autem omnis populus terrae et erit eis nominata dies in qua glorificatus sum ait Dominus Deus;", "brenton": "Yea, all the people of the land shall bury them; and it shall be to them a place of renown in the day wherein it was glorified, saith the Lord."}}, {"v": 14, "ref": "39:14", "o": "וְ/אַנְשֵׁ֨י תָמִ֤יד יַבְדִּ֨ילוּ֙ עֹבְרִ֣ים בָּ/אָ֔רֶץ מְקַבְּרִ֣ים אֶת הָ/עֹבְרִ֗ים אֶת הַ/נּוֹתָרִ֛ים עַל פְּנֵ֥י הָ/אָ֖רֶץ לְ/טַֽהֲרָ֑/הּ מִ/קְצֵ֥ה שִׁבְעָֽה חֳדָשִׁ֖ים יַחְקֹֽרוּ", "en": {"kjv": "And they shall sever out men of continual employment, passing through the land to bury with the passengers those that remain upon the face of the earth, to cleanse it: after the end of seven months shall they search.", "web": "They shall set apart men of continual employment, who shall pass through the land, and, with those who pass through, those who bury those who remain on the surface of the land, to cleanse it: after the end of seven months shall they search.", "bsb": "And men will be employed to continually pass through the land to cleanse it by burying the invaders who remain on the ground. At the end of the seven months they will begin their search.", "asv": "And they shall set apart men of continual employment, that shall pass through the land, and, with them that pass through, those that bury them that remain upon the face of the land, to cleanse it: after the end of seven months shall they search.", "ylt": "And men for continual employment they separate, passing on through the land, burying with those passing by those who are left on the face of the earth, to cleanse it: at the end of seven months they search.", "dra": "And they shall appoint men to go continually about the land, to bury and to seek out them that were remaining upon the face of the earth, that they may cleanse it: and after seven months they shall begin to seek.", "bbe": "And they will put on one side men to do no other work but to go through the land and put in the earth the rest of those who are still on the face of the land, to make it clean: after seven months are ended they are to make a search.", "geneva": "And they shall chuse out men to goe continually through the lande with them that trauaile, to bury those that remaine vpon ye ground, and clense it: they shall search to the ende of seuen moneths.", "wycliffe": "And thei schulen ordeyne bisili men cumpassynge the lond, that schulen birie and seke hem that weren left on the face of the lond, that thei clense it. Forsothe aftir seuene monethis thei schulen bigynne to seke,", "rotherham": "And, men to keep at it constantly, shall they tell off Men to pass throughout the land, who with the passers-by, shall continue burying, them who have been left on the face of the land to cleanse it,— At the end of seven months, shall they make search.", "darby": "And they shall sever out men of continual employment to go through the land, who, with the passers-by, shall bury those that remain upon the face of the land, to cleanse it: at the end of seven months shall they make a search.", "twenty": "", "jps": "And they shall set apart men of continual employment, that shall pass through the land to bury with them that pass through those that remain upon the face of the land, to cleanse it; after the end of seven months shall they search.", "acv": "And they shall set apart men of continual employment, who shall pass through the land. And, with those who pass through, those that bury those who remain upon the face of the land, to cleanse it, after the end of seven months they shall search.", "anderson": "", "haweis": "", "noyes": "And they shall set apart men to be constantly employed, who, passing through the land, with the aid of those that pass by, shall bury those that remain upon the face of the land to cleanse it; at the end of the seven months shall they search.", "webster": "And they shall sever out men of continual employment, passing through the land to bury with the passengers those that remain upon the face of the earth, to cleanse it: after the end of seven months shall they search.", "vulgate": "et viros iugiter constituent lustrantes terram qui sepeliant et requirant eos qui remanserant super faciem terrae ut emundent eam post menses autem septem quaerere incipient;", "brenton": "And they shall appoint men continually to go over the land, to bury them that have been left on the face of the earth, to cleanse it after the space of seven months, and they shall seek them out."}}, {"v": 15, "ref": "39:15", "o": "וְ/עָבְר֤וּ הָ/עֹֽבְרִים֙ בָּ/אָ֔רֶץ וְ/רָאָה֙ עֶ֣צֶם אָדָ֔ם וּ/בָנָ֥ה אֶצְל֖/וֹ צִיּ֑וּן עַ֣ד קָבְר֤וּ אֹת/וֹ֙ הַֽ/מְקַבְּרִ֔ים אֶל גֵּ֖יא הֲמ֥וֹן גּֽוֹג", "en": {"kjv": "And the passengers that pass through the land, when any seeth a man’s bone, then shall he set up a sign by it, till the buriers have buried it in the valley of Hamon–gog.", "web": "Those who pass through the land shall pass through; and when any sees a man’s bone, then shall he set up a sign by it, until the undertakers have buried it in the valley of Hamon Gog.", "bsb": "As they pass through the land, anyone who sees a human bone will set up a pillar next to it, until the gravediggers have buried it in the Valley of Hamon-gog.", "asv": "And they that pass through the land shall pass through; and when any seeth a man’s bone, then shall he set up a sign by it, till the buriers have buried it in the valley of Hamon-gog.", "ylt": "And those passing by have passed through the land, and seen a bone of man, and one hath constructed near it a sign till those burying have buried it in the valley of the multitude of Gog.", "dra": "And they shall go about passing through the land: and when they shall see the bone of a man, they shall set up sign by it, till the buriers bury it in the valley, of the multitude of Gog.", "bbe": "And while they go through the land, if anyone sees a man's bone, he is to put up a sign by the place till those who are doing the work have put it in the earth in the valley of Hamon-gog.", "geneva": "And the trauailers that passe through the land, if any see a mans bone, then shall he set vp a signe by it, till the buriers haue buried it, in the valley of Hamon-Gog.", "wycliffe": "and thei schulen cumpas goynge aboute the lond; and whanne thei schulen se the boon of a man, thei schulen sette a `notable signe bisidis it, til the birieris of careyns birie it in the valei of the multitude of Gog.", "rotherham": "And when any of the passers-by, in going through the land, shall see a human bone, then shall he set up near it a sign,—until the buriers have buried it, in Ge-hamon-Gog.", "darby": "And the passers-by shall pass through the land, and when [any] seeth a man's bone, he shall set up a sign by it, till the buriers have buried it in the Valley of Hamon-Gog.", "twenty": "", "jps": "And when they that pass through shall pass through the land, and any seeth a man's bone, then shall he set up a sign by it, till the buriers have buried it in the valley of Hamon-gog.", "acv": "And those who pass through the land shall pass through, and when any man sees a man's bone, then he shall set up a sign by it till the buriers have buried it in the valley of Hamon-gog.", "anderson": "", "haweis": "", "noyes": "And when any of the travellers that pass through the land shall see a man’s bone, they shall set up a sign by it, till the buriers have buried it in the valley of the multitude of Gog.", "webster": "And [as] passengers pass through the land, when [any] seeth a man's bone, then shall he set up a sign by it, till the buriers have buried it in the valley of Hamon-gog.", "vulgate": "et circumibunt peragrantes terram cumque viderint os hominis statuent iuxta illud titulum donec sepeliant illud pollinctores in valle Multitudinis Gog;", "brenton": "And every one that goes through the land, and sees a man's bone, shall set up a mark by it, until the buriers shall have buried it in the valley, the burial place of Gog."}}, {"v": 16, "ref": "39:16", "o": "וְ/גַ֥ם שֶׁם עִ֛יר הֲמוֹנָ֖ה וְ/טִהֲר֥וּ הָ/אָֽרֶץ", "en": {"kjv": "And also the name of the city shall be Hamonah. Thus shall they cleanse the land.", "web": "Hamonah shall also be the name of a city. Thus shall they cleanse the land.", "bsb": "(Even the city will be named Hamonah.) And so they will cleanse the land.", "asv": "And Hamonah shall also be the name of a city. Thus shall they cleanse the land.", "ylt": "And also the name of the city is The multitude; and they have cleansed the land.", "dra": "And the name of the city shall be Amona, and they shall cleanse the land.", "bbe": "And there they will put all the army of Gog in the earth. So they will make the land clean.", "geneva": "And also the name of the citie shalbe Hamonah: thus shall they clense the land.", "wycliffe": "Sotheli the name of the cite is Amona; and thei schulen clense the lond.", "rotherham": "Moreover, the name of a city, shall be Hamonah [\"To the multitude\"] so shall they cleanse the land.", "darby": "And also the name of the city shall be Hamonah. Thus shall they cleanse the land.", "twenty": "", "jps": "And Hamonah shall also be the name of a city. Thus shall they cleanse the land.", "acv": "And Hamonah shall also be the name of a city. Thus they shall cleanse the land.", "anderson": "", "haweis": "", "noyes": "Also the name of a city shall be Multitude. Thus shall they cleanse the land.", "webster": "And also the name of the city [shall be] Hamonah. Thus shall they cleanse the land.", "vulgate": "nomen autem civitatis Amona et mundabunt terram;", "brenton": "For the name of the city shall be Burial-place: so shall the land be cleansed."}}, {"v": 17, "ref": "39:17", "o": "וְ/אַתָּ֨ה בֶן אָדָ֜ם כֹּֽה אָמַ֣ר אֲדֹנָ֣/י יְהֹוִ֗ה אֱמֹר֩ לְ/צִפּ֨וֹר כָּל כָּנָ֜ף וּ/לְ/כֹ֣ל חַיַּ֣ת הַ/שָּׂדֶ֗ה הִקָּבְצ֤וּ וָ/בֹ֨אוּ֙ הֵאָסְפ֣וּ מִ/סָּבִ֔יב עַל זִבְחִ֗/י אֲשֶׁ֨ר אֲנִ֜י זֹבֵ֤חַ לָ/כֶם֙ זֶ֣בַח גָּד֔וֹל עַ֖ל הָרֵ֣י יִשְׂרָאֵ֑ל וַ/אֲכַלְתֶּ֥ם בָּשָׂ֖ר וּ/שְׁתִ֥יתֶם דָּֽם", "en": {"kjv": "And, thou son of man, thus saith the Lord God; Speak unto every feathered fowl, and to every beast of the field, Assemble yourselves, and come; gather yourselves on every side to my sacrifice that I do sacrifice for you, even a great sacrifice upon the mountains of Israel, that ye may eat flesh, and drink blood.", "web": "You, son of man, thus says the Lord Yahweh: Speak to the birds of every sort, and to every animal of the field, Assemble yourselves, and come; gather yourselves on every side to my sacrifice that I do sacrifice for you, even a great sacrifice on the mountains of Israel, that you may eat flesh and drink blood.", "bsb": "And as for you, son of man, this is what the Lord GOD says: Call out to every kind of bird and to every beast of the field: ‘Assemble and come together from all around to the sacrificial feast that I am preparing for you, a great feast on the mountains of Israel. There you will eat flesh and drink blood.", "asv": "And thou, son of man, thus saith the Lord Jehovah: Speak unto the birds of every sort, and to every beast of the field, Assemble yourselves, and come; gather yourselves on every side to my sacrifice that I do sacrifice for you, even a great sacrifice upon the mountains of Israel, that ye may eat flesh and drink blood.", "ylt": "And thou, son of man, thus said the Lord Jehovah: Say to the bird--every wing, and to every beast of the field: Be assembled and come in, Be gathered from round about, For My sacrifice that I am sacrificing for you, A great sacrifice on mountains of Israel, And ye have eaten flesh, and drunk blood.", "dra": "And thou, O son of man, saith the Lord God, say to every fowl, and to all the birds, and to all the beasts of the field: Assemble yourselves, make haste, come together from every side to my victim, which I slay for you, a great victim upon the mountains of Israel: to eat flesh, and drink blood.", "bbe": "And you, son of man, this is what the Lord has said: Say to the birds of every sort and to all the beasts of the field, Get together and come; come together on every side to the offering which I am putting to death for you, a great offering on the mountains of Israel, so that you may have flesh for your food and blood for your drink.", "geneva": "And thou sonne of man, thus sayeth the Lord God, Speake vnto euery feathered foule, and to all the beastes of the fielde, Assemble your selues, and come gather your selues on euery side to my sacrifice: for I do sacrifice a great sacrifice for you vpon the mountaines of Israel, that ye may eate flesh, and drinke blood.", "wycliffe": "Forsothe, thou, sone of man, the Lord God seith these thingis, Seie thou to ech brid, and to alle foulis, and to alle beestis of the feeld, Come ye to gidere, and haste ye, renne ye togidere on ech side to my sacrifice, which Y sle to you, a greet sacrifice on the hillis of Israel, that ye ete fleischis and drynke blood.", "rotherham": "Thou, therefore son of man, Thus, saith My Lord Yahweh, Say to the bird of every wing. And to every wild beast of the field. Assemble yourselves and come Gather yourselves from every side, unto my sacrifice which I am sacrificing for you A great sacrifice on the mountains of Israel,- And ye shall eat flesh and drink blood:", "darby": "And thou, son of man, thus saith the Lord Jehovah: Speak unto the birds of every wing, and to every beast of the field, Gather yourselves together and come, assemble yourselves on every side to my sacrifice which I sacrifice for you, a great sacrifice upon the mountains of Israel, that ye may eat flesh, and drink blood.", "twenty": "", "jps": "And thou, son of man, thus saith the L-rd GOD: Speak unto the birds of every sort, and to every beast of the field: Assemble yourselves, and come; gather yourselves on every side to My feast that I do prepare for you, even a great feast, upon the mountains of Israel, that ye may eat flesh and drink blood.", "acv": "And thou, son of man, thus says the lord Jehovah: Speak to the birds of every sort, and to every beast of the field, Assemble yourselves, and come. Gather yourselves on every side to my sacrifice that I sacrifice for you, even a great sacrifice upon the mountains of Israel, that ye may eat flesh and drink blood.", "anderson": "", "haweis": "", "noyes": "And thou, son of man, thus saith the Lord Jehovah: Say to the birds of every wing, and to every beast of the field, Assemble yourselves and come, gather yourselves from every side to my sacrifice which I make for you, a great sacrifice upon the mountains of Israel; and ye shall eat flesh and drink blood;", "webster": "And, thou son of man, thus saith the Lord GOD; Speak to every feathered fowl, and to every beast of the field, Assemble yourselves, and come; gather yourselves on every side to my sacrifice that I do sacrifice for you, [even] a great sacrifice upon the mountains of Israel, that ye may eat flesh, and drink blood.", "vulgate": "tu ergo fili hominis haec dicit Dominus Deus dic omni volucri et universis avibus cunctisque bestiis agri convenite properate concurrite undique ad victimam meam quam ego immolo vobis victimam grandem super montes Israhel ut comedatis carnes et bibatis sanguinem;", "brenton": "And thou, son of man, say, Thus saith the Lord; Say to every winged bird, and to all the wild beasts of the field, Gather yourselves, and come; gather yourselves from all places round about to my sacrifice, which I have made for you, even a great sacrifice on the mountains of Israel, and ye shall eat flesh, and drink blood."}}, {"v": 18, "ref": "39:18", "o": "בְּשַׂ֤ר גִּבּוֹרִים֙ תֹּאכֵ֔לוּ וְ/דַם נְשִׂיאֵ֥י הָ/אָ֖רֶץ תִּשְׁתּ֑וּ אֵילִ֨ים כָּרִ֤ים וְ/עַתּוּדִים֙ פָּרִ֔ים מְרִיאֵ֥י בָשָׁ֖ן כֻּלָּֽ/ם", "en": {"kjv": "Ye shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, of bullocks, all of them fatlings of Bashan.", "web": "You shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, of bulls, all of them fatlings of Bashan.", "bsb": "You will eat the flesh of the mighty and drink the blood of the princes of the earth as though they were rams, lambs, goats, and bulls—all the fattened animals of Bashan.", "asv": "Ye shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, of bullocks, all of them fatlings of Bashan.", "ylt": "Flesh of the mighty ye do eat, And blood of princes of the earth ye drink, Of rams, of lambs, and of he-goats, Of calves, fatlings of Bashan--all of them.", "dra": "You shall eat the flesh of the mighty, and you shall drink the blood of the princes of the earth, of rams, and of lambs, and of he goats, and bullocks, and of all that are well fed and fat.", "bbe": "The flesh of the men of war will be your food, and your drink the blood of the princes of the earth, of sheep and lambs, of he-goats, of oxen, all of them fat beasts of Bashan.", "geneva": "Ye shall eate the flesh of the valiant, and drink the blood of the princes of the earth, of the weathers, of the lambes, and of the goates, and of bullockes, euen of all fat beastes of Bashan.", "wycliffe": "Ye schulen ete the fleischis of stronge men, and ye schulen drynke the blood of prynces of erthe, of wetheris, of lambren, and of buckis of geet, and of bolis, and of beestis maad fat, and of alle fat thingis.", "rotherham": "The flesh of mighty men, shall ye eat, And the blood of the princes of the earth, shall ye drink.— Rams well-fed lambs and he-goats bullocks, Fatlings of Bashan all of them;", "darby": "Ye shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, [and] of bullocks, all of them fatted beasts of Bashan.", "twenty": "", "jps": "The flesh of the mighty shall ye eat, and the blood of the princes of the earth shall ye drink; rams, lambs, and goats, bullocks, fatlings of Bashan are they all of them.", "acv": "Ye shall eat the flesh of the mighty, and drink the blood of the rulers of the earth, of rams, of lambs, and of goats, of bullocks, all of them fatlings of Bashan.", "anderson": "", "haweis": "", "noyes": "the flesh of the mighty shall ye eat, and the blood of the princes of the earth shall ye drink, of rams, of lambs, and of goats, of bullocks, all of them fatted in Bashan.", "webster": "Ye shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, of bullocks, all of them fatlings of Bashan.", "vulgate": "carnes fortium comedetis et sanguinem principum terrae bibetis arietum agnorum et hircorum taurorumque altilium et pinguium omnium;", "brenton": "Ye shall eat the flesh of mighty men, and ye shall drink the blood of princes of the earth, rams, and calves and goats, and they are all fatted calves."}}, {"v": 19, "ref": "39:19", "o": "וַ/אֲכַלְתֶּם חֵ֣לֶב לְ/שָׂבְעָ֔ה וּ/שְׁתִ֥יתֶם דָּ֖ם לְ/שִׁכָּר֑וֹן מִ/זִּבְחִ֖/י אֲשֶׁר זָבַ֥חְתִּי לָ/כֶֽם", "en": {"kjv": "And ye shall eat fat till ye be full, and drink blood till ye be drunken, of my sacrifice which I have sacrificed for you.", "web": "You shall eat fat until you be full, and drink blood until you are drunk, of my sacrifice which I have sacrificed for you.", "bsb": "At the sacrifice I am preparing, you will eat fat until you are gorged and drink blood until you are drunk.", "asv": "And ye shall eat fat till ye be full, and drink blood till ye be drunken, of my sacrifice which I have sacrificed for you.", "ylt": "And ye have eaten fat to satiety, And ye have drunk blood--to drunkenness, Of My sacrifice that I sacrificed for you.", "dra": "And you shall eat the fat till you be full, and shall drink blood till you be drunk of the victim which I shall slay for you.", "bbe": "You will go on feasting on the fat till you are full, and drinking the blood till you are overcome with it, of my offering which I have put to death for you.", "geneva": "And ye shall eate fat till you be full, and drinke blood, till ye be drunken of my sacrifice, which I haue sacrificed for you.", "wycliffe": "And ye schulen ete the ynnere fatnesse in to fulnesse, and ye schulen drynke the blood in to drunkenesse, of the sacrifice which Y schal sle to you.", "rotherham": "And ye shall eat fat till ye are sated, And drink blood till ye are drunken, Of my sacrifice which I have sacrificed for you;", "darby": "And ye shall eat fat till ye are full, and drink blood till ye are drunken, of my sacrifice which I sacrifice for you.", "twenty": "", "jps": "And ye shall eat fat till ye be full, and drink blood till ye be drunken, of My feast which I have prepared for you.", "acv": "And ye shall eat fat till ye be full, and drink blood till ye be drunken, of my sacrifice which I have sacrificed for you.", "anderson": "", "haweis": "", "noyes": "And ye shall eat fat till ye be full, and drink blood till ye be drunken, of my sacrifice which I make for you.", "webster": "And ye shall eat fat till ye are full, and drink blood till ye are drunken, of my sacrifice which I have sacrificed for you.", "vulgate": "et comedetis adipem in saturitate et bibetis sanguinem in ebrietate de victima quam ego immolabo vobis;", "brenton": "And ye shall eat fat till ye are full, and shall drink wine till ye are drunken, of my sacrifice which I have prepared for you."}}, {"v": 20, "ref": "39:20", "o": "וּ/שְׂבַעְתֶּ֤ם עַל שֻׁלְחָנִ/י֙ ס֣וּס וָ/רֶ֔כֶב גִּבּ֖וֹר וְ/כָל אִ֣ישׁ מִלְחָמָ֑ה נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thus ye shall be filled at my table with horses and chariots, with mighty men, and with all men of war, saith the Lord God.", "web": "You shall be filled at my table with horses and chariots, with mighty men, and with all men of war, says the Lord Yahweh.", "bsb": "And at My table you will eat your fill of horses and riders, of mighty men and warriors of every kind,’ declares the Lord GOD.", "asv": "And ye shall be filled at my table with horses and chariots, with mighty men, and with all men of war, saith the Lord Jehovah.", "ylt": "And ye have been satisfied at My table with horse and rider, Mighty man, and every man of war, An affirmation of the Lord Jehovah.", "dra": "And you shall be filled at my table with horses, and mighty horsemen, and all the men of war, saith the Lord God.", "bbe": "At my table you will have food in full measure, horses and war-carriages, great men and all the men of war, says the Lord.", "geneva": "Thus you shalbe filled at my table with horses and chariots, with valiant men, and with al men of warre, sayth the Lord God.", "wycliffe": "And ye schulen be fillid on my boord, of hors, and of strong horse man, and of alle men werriours, seith the Lord God.", "rotherham": "So shall ye be sated at my table with horse and chariot team, mighty man and every man of war,— Declareth My Lord, Yahweh.", "darby": "And ye shall be filled at my table with horses and charioteers, with mighty men, and with all men of war, saith the Lord Jehovah.", "twenty": "", "jps": "And ye shall be filled at My table with horses and horsemen, with mighty men, and with all men of war, saith the L-rd GOD.", "acv": "And ye shall be filled at my table with horses and chariots, with mighty men, and with all men of war, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus shall ye be filled at my table with horses and riders, and mighty men and warriors of all kinds, saith the Lord Jehovah.", "webster": "Thus ye shall be filled at my table with horses and chariots, with mighty men, and with all men of war, saith the Lord GOD.", "vulgate": "et saturabimini super mensam meam de equo et de equite forti et de universis viris bellatoribus ait Dominus Deus;", "brenton": "And ye shall be filled at my table, eating horse, and rider, and mighty man, and every warrior, saith the Lord."}}, {"v": 21, "ref": "39:21", "o": "וְ/נָתַתִּ֥י אֶת כְּבוֹדִ֖/י בַּ/גּוֹיִ֑ם וְ/רָא֣וּ כָל הַ/גּוֹיִ֗ם אֶת מִשְׁפָּטִ/י֙ אֲשֶׁ֣ר עָשִׂ֔יתִי וְ/אֶת יָדִ֖/י אֲשֶׁר שַׂ֥מְתִּי בָ/הֶֽם", "en": {"kjv": "And I will set my glory among the heathen, and all the heathen shall see my judgment that I have executed, and my hand that I have laid upon them.", "web": "I will set my glory among the nations; and all the nations shall see my judgment that I have executed, and my hand that I have laid on them.", "bsb": "I will display My glory among the nations, and all the nations will see the judgment that I execute and the hand that I lay upon them.", "asv": "And I will set my glory among the nations; and all the nations shall see my judgment that I have executed, and my hand that I have laid upon them.", "ylt": "And I have given My honour among nations, And seen have all the nations My Judgment that I have done, And My hand that I have laid on them.", "dra": "And I will set my glory among the nations: and all nations shall see my judgment that I have executed, and my hand that I have laid upon them.", "bbe": "And I will put my glory among the nations, and all the nations will see my punishments which I have put into effect, and my hand which I have put on them.", "geneva": "And I wil set my glory among the heathe, and all the heathen shall see my iudgement, that I haue executed, and mine hand, which I haue layed vpon them.", "wycliffe": "And Y schal sette my glorie among hethene men, and alle hethene men schulen se my doom, which Y haue do, and myn hond, which Y haue set on hem.", "rotherham": "Thus will I set my glory among the nations, And all the nations, shall see, My judgment which I have executed,—and My hand which I have laid upon them.", "darby": "And I will set my glory among the nations, and all the nations shall see my judgment which I have executed, and my hand which I have laid upon them.", "twenty": "", "jps": "And I will set My glory among the nations, and all the nations shall see My judgment that I have executed, and My hand that I have laid upon them.", "acv": "And I will set my glory among the nations. And all the nations shall see my judgment that I have executed, and my hand that I have laid upon them.", "anderson": "", "haweis": "", "noyes": "And I will set my glory among the nations, and all the nations shall see my judgment which I have executed, and my hand which I have laid upon them.", "webster": "And I will set my glory among the heathen, and all the heathen shall see my judgment that I have executed, and my hand that I have laid upon them.", "vulgate": "et ponam gloriam meam in gentibus et videbunt omnes gentes iudicium meum quod fecerim et manum meam quam posuerim super eos;", "brenton": "And I will set my glory among you, and all the nations shall see my judgment which I have wrought, and my hand which I have brought upon them."}}, {"v": 22, "ref": "39:22", "o": "וְ/יָֽדְעוּ֙ בֵּ֣ית יִשְׂרָאֵ֔ל כִּ֛י אֲנִ֥י יְהוָ֖ה אֱלֹֽהֵי/הֶ֑ם מִן הַ/יּ֥וֹם הַ/ה֖וּא וָ/הָֽלְאָה", "en": {"kjv": "So the house of Israel shall know that I am the Lord their God from that day and forward.", "web": "So the house of Israel shall know that I am Yahweh their God, from that day and forward.", "bsb": "From that day forward the house of Israel will know that I am the LORD their God.", "asv": "So the house of Israel shall know that I am Jehovah their God, from that day and forward.", "ylt": "And known have the house of Israel that I am Jehovah their God, From that day and henceforth.", "dra": "And the house of Israel shall know that I am the Lord their God from that day and forward.", "bbe": "So the children of Israel will be certain that I am the Lord their God, from that day and for the future.", "geneva": "So the house of Israel shall knowe, that I am the Lord their God from that day and so forth.", "wycliffe": "And the hous of Israel schulen wite, that Y am her Lord God, fro that dai and afterward.", "rotherham": "So shall the house of Israel know that, I Yahweh, am their God,—from that day and forward;", "darby": "And the house of Israel shall know that I [am] Jehovah theirGod from that day and forward.", "twenty": "", "jps": "So the house of Israel shall know that I am HaShem their G-d, from that day and forward.", "acv": "So the house of Israel shall know that I am Jehovah their God, from that day and forward.", "anderson": "", "haweis": "", "noyes": "And the house of Israel shall know that I am Jehovah, their God, from that day and forward.", "webster": "So the house of Israel shall know that I [am] the LORD their God from that day and forward.", "vulgate": "et scient domus Israhel quia ego Dominus Deus eorum a die illa et deinceps;", "brenton": "And the house of Israel shall know that I am the Lord their God, from this day and onwards."}}, {"v": 23, "ref": "39:23", "o": "וְ/יָדְע֣וּ הַ֠/גּוֹיִם כִּ֣י בַ/עֲוֺנָ֞/ם גָּל֣וּ בֵֽית יִשְׂרָאֵ֗ל עַ֚ל אֲשֶׁ֣ר מָֽעֲלוּ בִ֔/י וָ/אַסְתִּ֥ר פָּנַ֖/י מֵ/הֶ֑ם וָֽ/אֶתְּנֵ/ם֙ בְּ/יַ֣ד צָרֵי/הֶ֔ם וַ/יִּפְּל֥וּ בַ/חֶ֖רֶב כֻּלָּֽ/ם", "en": {"kjv": "And the heathen shall know that the house of Israel went into captivity for their iniquity: because they trespassed against me, therefore hid I my face from them, and gave them into the hand of their enemies: so fell they all by the sword.", "web": "The nations shall know that the house of Israel went into captivity for their iniquity; because they trespassed against me, and I hid my face from them: so I gave them into the hand of their adversaries, and they fell all of them by the sword.", "bsb": "And the nations will know that the house of Israel went into exile for their iniquity, because they were unfaithful to Me. So I hid My face from them and delivered them into the hands of their enemies, so that they all fell by the sword.", "asv": "And the nations shall know that the house of Israel went into captivity for their iniquity; because they trespassed against me, and I hid my face from them: so I gave them into the hand of their adversaries, and they fell all of them by the sword.", "ylt": "And known have the nations that for their iniquity, Removed have the house of Israel, Because they have trespassed against Me, And I do hide My face from them, And give them into the hand of their adversaries, And they fall by sword--all of them.", "dra": "And the nations shall know that the house of Israel were made captives for their iniquity, because they forsook me, and I hid my face from them: and I delivered them into the hands of their enemies, and they fell all by the sword.", "bbe": "And it will be clear to the nations that the children of Israel were taken away prisoners for their evil-doing; because they did wrong against me, and my face was covered from them: so I gave them up into the hands of their attackers, and they all came to their end by the sword.", "geneva": "And the heathen shall knowe, that ye house of Israel went into captiuitie for their iniquitie, because they trespassed against me: therefore hid I my face from them, and gaue them into ye hand of their enemies: so fell they all by the sword.", "wycliffe": "And hethen men schulen wite, that the hous of Israel is takun in her wickidnesse, for that that thei forsoken me; and Y hidde my face fro hem, and Y bitook hem into the hondis of enemyes, and alle thei fellen doun bi swerd.", "rotherham": "And the nations shall know That in their iniquity, were the house of Israel exiled because they had committed treachery against me, And so I hid my face from them,— And gave them into the hand of their adversaries, And they fell by the sword all of them.", "darby": "And the nations shall know that the house of Israel went into captivity for their iniquity, because they were unfaithful against me; and I hid my face from them, and gave them into the hand of their enemies, so that they fell all of them by the sword.", "twenty": "", "jps": "And the nations shall know that the house of Israel went into captivity for their iniquity, because they broke faith with Me, and I hid My face from them; so I gave them into the hand of their adversaries, and they fell all of them by the sword.", "acv": "And the nations shall know that the house of Israel went into captivity for their iniquity, because they trespassed against me, and I hid my face from them. So I gave them into the hand of their adversaries, and they fell all of them by the sword.", "anderson": "", "haweis": "", "noyes": "And the nations shall know that the house of Israel were carried into captivity for their iniquity. Because they trespassed against me, therefore hid I my face from them, and gave them into the hand of their enemies, so that they all fell by the sword.", "webster": "And the heathen shall know that the house of Israel went into captivity for their iniquity: because they trespassed against me, therefore I hid my face from them, and gave them into the hand of their enemies: so they all fell by the sword.", "vulgate": "et scient gentes quoniam in iniquitate sua capta sit domus Israhel eo quod reliquerint me et absconderim faciem meam ab eis et tradiderim eos in manu hostium et ceciderint in gladio universi;", "brenton": "And all the nations shall know that the house of Israel were led captive because of their sins, because they rebelled against me, and I turned away my face from them, and delivered them into the hands of their enemies, and they all fell by the sword."}}, {"v": 24, "ref": "39:24", "o": "כְּ/טֻמְאָתָ֥/ם וּ/כְ/פִשְׁעֵי/הֶ֖ם עָשִׂ֣יתִי אֹתָ֑/ם וָ/אַסְתִּ֥ר פָּנַ֖/י מֵ/הֶֽם", "en": {"kjv": "According to their uncleanness and according to their transgressions have I done unto them, and hid my face from them.", "web": "According to their uncleanness and according to their transgressions did I to them; and I hid my face from them.", "bsb": "I dealt with them according to their uncleanness and transgressions, and I hid My face from them.", "asv": "According to their uncleanness and according to their transgressions did I unto them; and I hid my face from them.", "ylt": "According to their uncleanness, And according to their transgressions, I have done with them, And I do hide My face from them.", "dra": "I have dealt with them according to their uncleanness, and wickedness, and hid my face from them.", "bbe": "In the measure of their unclean ways and their sins, so I did to them; and I kept my face covered from them.", "geneva": "According to their vncleannes, and according to their transgressions haue I done vnto the, and hid my face from them.", "wycliffe": "Bi the unclennes and greet trespasse of hem Y dide to hem, and Y hidde my face fro hem.", "rotherham": "According to their uncleanness and according to their transgressions, dealt I with them,— And so I hid my face from them.", "darby": "According to their uncleanness and according to their transgressions I did unto them, and I hid my face from them.", "twenty": "", "jps": "According to their uncleanness and according to their transgressions did I unto them; and I hid My face from them.", "acv": "I did to them according to their uncleanness and according to their transgressions. And I hid my face from them.", "anderson": "", "haweis": "", "noyes": "According to their uncleanness and according to their transgressions have I dealt with them, and hid my face from them.", "webster": "According to their uncleanness and according to their transgressions have I done to them, and hid my face from them.", "vulgate": "iuxta inmunditiam eorum et scelus feci eis et abscondi faciem meam ab illis;", "brenton": "According to their uncleannesses and according to their transgressions did I deal with them, and I turned away my face from them."}}, {"v": 25, "ref": "39:25", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה עַתָּ֗ה אָשִׁיב֙ אֶת שבית שְׁב֣וּת יַֽעֲקֹ֔ב וְ/רִֽחַמְתִּ֖י כָּל בֵּ֣ית יִשְׂרָאֵ֑ל וְ/קִנֵּאתִ֖י לְ/שֵׁ֥ם קָדְשִֽׁ/י", "en": {"kjv": "Therefore thus saith the Lord God; Now will I bring again the captivity of Jacob, and have mercy upon the whole house of Israel, and will be jealous for my holy name;", "web": "Therefore thus says the Lord Yahweh: Now will I bring back the captivity of Jacob, and have mercy on the whole house of Israel; and I will be jealous for my holy name.", "bsb": "Therefore this is what the Lord GOD says: Now I will restore Jacob from captivity and will have compassion on the whole house of Israel, and I will be jealous for My holy name.", "asv": "Therefore thus saith the Lord Jehovah: Now will I bring back the captivity of Jacob, and have mercy upon the whole house of Israel; and I will be jealous for my holy name.", "ylt": "Therefore, thus said the Lord Jehovah: Now do I bring back the captivity of Jacob, And I have pitied all the house of Israel, And have been zealous for My holy name.", "dra": "Therefore, thus saith the Lord God: Now will I bring back the captivity of Jacob, and will have mercy on all the house of Israel and I will be jealous for my holy name.", "bbe": "For this cause the Lord has said, Now I will let the fate of Jacob be changed, and I will have mercy on all the children of Israel, and will take care of the honour of my holy name.", "geneva": "Therefore thus sayth the Lord God, Nowe will I bring againe the captiuitie of Iaakob, and haue compassion vpon the whole house of Israel, and wil be ielous for mine holy Name,", "wycliffe": "Therfor the Lord God seith these thingis, Now Y schal leede ayen the caitiftee of Jacob, and Y schal haue merci on al the hous of Israel; and Y schal take feruoure for myn hooli name.", "rotherham": "Therefore— Thus saith My Lord Yahweh, Now, will I bring back them of the captivity of Jacob, And have compassion upon all the house of Israel,- And will be jealous for my holy Name;", "darby": "Therefore, thus saith the Lord Jehovah: Now will I bring again the captivity of Jacob, and have mercy upon the whole house of Israel, and will be jealous for my holy name:", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Now will I bring back the captivity of Jacob, and have compassion upon the whole house of Israel; and I will be jealous for My holy name.", "acv": "Therefore thus says the lord Jehovah: Now I will bring back the captivity of Jacob, and have mercy upon the whole house of Israel. And I will be jealous for my holy name.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: I will bring back the captives of Jacob, and have compassion upon the whole house of Israel, and be jealous for my holy name.", "webster": "Therefore thus saith the Lord GOD; Now will I bring again the captivity of Jacob, and have mercy upon the whole house of Israel, and will be jealous for my holy name;", "vulgate": "propterea haec dicit Dominus Deus nunc reducam captivitatem Iacob et miserebor omnis domus Israhel et adsumam zelum pro nomine sancto meo;", "brenton": "Therefore thus saith the Lord God, Now will I turn back captivity in Jacob, and will have mercy on the house of Israel, and will be jealous for the sake of my holy name."}}, {"v": 26, "ref": "39:26", "o": "וְ/נָשׂוּ֙ אֶת כְּלִמָּתָ֔/ם וְ/אֶת כָּל מַעֲלָ֖/ם אֲשֶׁ֣ר מָעֲלוּ בִ֑/י בְּ/שִׁבְתָּ֧/ם עַל אַדְמָתָ֛/ם לָ/בֶ֖טַח וְ/אֵ֥ין מַחֲרִֽיד", "en": {"kjv": "After that they have borne their shame, and all their trespasses whereby they have trespassed against me, when they dwelt safely in their land, and none made them afraid.", "web": "They shall bear their shame, and all their trespasses by which they have trespassed against me, when they shall dwell securely in their land, and no one shall make them afraid;", "bsb": "They will forget their disgrace and all the treachery they committed against Me, when they dwell securely in their land, with no one to frighten them.", "asv": "And they shall bear their shame, and all their trespasses whereby they have trespassed against me, when they shall dwell securely in their land, and none shall make them afraid;", "ylt": "And they have forgotten their shame, And all their trespass that they trespassed against Me, In their dwelling on their land confidently and none troubling.", "dra": "And they shall bear their confusion, and all the transgressions wherewith they have transgressed against me, when they shall dwell in their land securely fearing no man:", "bbe": "And they will be conscious of their shame and of all the wrong which they have done against me, when they are living in their land with no sense of danger and with no one to be a cause of fear to them;", "geneva": "After that they haue borne their shame, and all their transgression, whereby they haue transgressed against me, whe they dwelt safely in their land, and without feare of any.", "wycliffe": "And thei schulen bere here schenschipe, and al the trespassing bi which thei trespassiden ayens me, whanne thei dwelliden in her lond tristili, and dredden no man;", "rotherham": "And they shall bear their confusion, and the punishment of all their treachery wherewith they have committed treachery against me,- When they dwell upon their own soil securely, with none to make them afraid;", "darby": "and they shall bear their confusion, and all their unfaithfulness in which they have acted unfaithfully against me, when they shall dwell safely in their land, and none shall make them afraid;", "twenty": "", "jps": "And they shall bear their shame, and all their breach of faith which they have committed against Me, when they shall dwell safely in their land, and none shall make them afraid;", "acv": "And they shall bear their shame, and all their trespasses by which they have trespassed against me, when they shall dwell securely in their land. And none shall make them afraid", "anderson": "", "haweis": "", "noyes": "Then shall they forget their shame and all their trespasses with which they trespassed against me, when they dwell in security in their own land, and none maketh them afraid.", "webster": "After they have borne their shame, and all their trespasses by which they have trespassed against me, when they dwelt safely in their land, and none made [them] afraid.", "vulgate": "et portabunt confusionem suam et omnem praevaricationem quam praevaricati sunt in me cum habitaverint in terra sua confidenter neminem formidantes;", "brenton": "And they shall bear their reproach, and the iniquity which they committed when they dwelt upon their land in peace. Yet there shall be none to terrify them"}}, {"v": 27, "ref": "39:27", "o": "בְּ/שׁוֹבְבִ֤/י אוֹתָ/ם֙ מִן הָ֣/עַמִּ֔ים וְ/קִבַּצְתִּ֣י אֹתָ֔/ם מֵֽ/אַרְצ֖וֹת אֹֽיְבֵי/הֶ֑ם וְ/נִקְדַּ֣שְׁתִּי בָ֔/ם לְ/עֵינֵ֖י הַ/גּוֹיִ֥ם רַבִּֽים", "en": {"kjv": "When I have brought them again from the people, and gathered them out of their enemies’ lands, and am sanctified in them in the sight of many nations;", "web": "when I have brought them back from the peoples, and gathered them out of their enemies’ lands, and am sanctified in them in the sight of many nations.", "bsb": "When I bring them back from the peoples and gather them out of the lands of their enemies, I will show My holiness in them in the sight of many nations.", "asv": "when I have brought them back from the peoples, and gathered them out of their enemies’ lands, and am sanctified in them in the sight of many nations.", "ylt": "In My bringing them back from the peoples, I have assembled them from the lands of their enemies, And I have been sanctified in them before the eyes of the many nations,", "dra": "And I shall have brought them back from among the nations, and shall have gathered them together out of the lands of their enemies, and shall be sanctified in them, in the sight of many nations.", "bbe": "When I have taken them back from among the peoples and got them together out of the lands of their haters, and have made myself holy in them before the eyes of a great number of nations.", "geneva": "When I haue brought them againe from the people, and gathered them out of their enemies landes, and am sanctified in them in the sight of many nations,", "wycliffe": "and whanne Y schal bringe hem ayen fro puplis, and schal gadere fro the londis of her enemyes, and schal be halewid in hem, bifor the iyen of ful many folkis.", "rotherham": "When I have brought them back from among the peoples, And gathered them out of the lands of their enemies,- So will I hallow myself in them, before the eyes of the many nations;", "darby": "when I have brought them again from the peoples, and gathered them out of their enemies' lands, and am hallowed in them in the sight of many nations.", "twenty": "", "jps": "when I have brought them back from the peoples, and gathered them out of their enemies' lands, and am sanctified in them in the sight of many nations.", "acv": "when I have brought them back from the peoples, and gathered them out of their enemies' lands, and am sanctified in them in the sight of many nations.", "anderson": "", "haweis": "", "noyes": "When I bring them back from the nations, and gather them from the lands of their enemies, then will I be glorified in regard to them before the eyes of many nations.", "webster": "When I have brought them again from the people, and gathered them out of the lands of their enemies, and am sanctified in them in the sight of many nations;", "vulgate": "et reduxero eos de populis et congregavero de terris inimicorum suorum et sanctificatus fuero in eis in oculis gentium plurimarum;", "brenton": "when I have brought them back from the nations, and gathered them out of the countries of the nations: and I will be sanctified among them in the presence of the nations."}}, {"v": 28, "ref": "39:28", "o": "וְ/יָדְע֗וּ כִּ֣י אֲנִ֤י יְהוָה֙ אֱלֹ֣הֵי/הֶ֔ם בְּ/הַגְלוֹתִ֤/י אֹתָ/ם֙ אֶל הַ/גּוֹיִ֔ם וְ/כִנַּסְתִּ֖י/ם עַל אַדְמָתָ֑/ם וְ/לֹֽא אוֹתִ֥יר ע֛וֹד מֵ/הֶ֖ם שָֽׁם", "en": {"kjv": "Then shall they know that I am the Lord their God, which caused them to be led into captivity among the heathen: but I have gathered them unto their own land, and have left none of them any more there.", "web": "They shall know that I am Yahweh their God, in that I caused them to go into captivity among the nations, and have gathered them to their own land; and I will leave none of them any more there;", "bsb": "Then they will know that I am the LORD their God, when I regather them to their own land, not leaving any of them behind after their exile among the nations.", "asv": "And they shall know that I am Jehovah their God, in that I caused them to go into captivity among the nations, and have gathered them unto their own land; and I will leave none of them any more there;", "ylt": "And they have known that I am Jehovah their God, In My removing them unto the nations, And I have gathered them unto their land, And I leave none of them any more there.", "dra": "And they shall know that I am the Lord their God, because I caused them to be carried away among the nations; and I have gathered them together unto their own land, and have not left any of them there.", "bbe": "And they will be certain that I am the Lord their God, because I sent them away as prisoners among the nations, and have taken them together back to their land; and I have not let one of them be there any longer.", "geneva": "Then shall they know, that I am the Lord their God, which caused them to be led into captiuitie among the heathen: but I haue gathered them vnto their owne land, and haue left none of them any more there,", "wycliffe": "And thei schulen wite, that Y am the Lord God of hem, for that Y translatide hem in to naciouns, and haue gaderid hem on her lond, and Y lefte not ony of hem there.", "rotherham": "And they shall know that, I Yahweh, am their God, When I have carried them into exile among the nations, And shall then gather them upon their own soil,- And shall no more leave any of them there.", "darby": "And they shall know that I [am] Jehovah theirGod, in that I caused them to be led into captivity among the nations, and have gathered them unto their own land, and have left none of them any more there.", "twenty": "", "jps": "And they shall know that I am HaShem their G-d, in that I caused them to go into captivity among the nations, and have gathered them unto their own land; and I will leave none of them any more there;", "acv": "And they shall know that I am Jehovah their God, in that I caused them to go into captivity among the nations, and have gathered them to their own land. And I will leave none of them any more there,", "anderson": "", "haweis": "", "noyes": "And they shall know that I am Jehovah their God, in that I caused them to be carried into captivity among the nations, and gathered them into their own land, and left none of them there.", "webster": "Then shall they know that I [am] the LORD their God, who caused them to be led into captivity among the heathen: but I have gathered them to their own land, and have left none of them there any more.", "vulgate": "et scient quia ego Dominus Deus eorum eo quod transtulerim eos in nationes et congregavero eos super terram suam et non dereliquerim quemquam ex eis ibi;", "brenton": "And they shall know that I am the Lord their God, when I have been manifested to them among the nations."}}, {"v": 29, "ref": "39:29", "o": "וְ/לֹֽא אַסְתִּ֥יר ע֛וֹד פָּנַ֖/י מֵ/הֶ֑ם אֲשֶׁ֨ר שָׁפַ֤כְתִּי אֶת רוּחִ/י֙ עַל בֵּ֣ית יִשְׂרָאֵ֔ל נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Neither will I hide my face any more from them: for I have poured out my spirit upon the house of Israel, saith the Lord God.", "web": "neither will I hide my face any more from them; for I have poured out my Spirit on the house of Israel, says the Lord Yahweh.", "bsb": "And I will no longer hide My face from them, for I will pour out My Spirit on the house of Israel, declares the Lord GOD.”", "asv": "neither will I hide my face any more from them; for I have poured out my Spirit upon the house of Israel, saith the Lord Jehovah.", "ylt": "And I hide not any more My face from them, In that I have poured out My spirit on the house of Israel, An affirmation of the Lord Jehovah!'", "dra": "And I will hide my face no more from them, for I have poured out my spirit upon all the house of Israel, saith the Lord God.", "bbe": "And my face will no longer be covered from them: for I have sent the out-flowing of my spirit on the children of Israel, says the Lord.", "geneva": "Neither wil I hide my face any more from them: for I haue powred out my Spirit vpon the house of Israel, sayth the Lord God.", "wycliffe": "And Y schal no more hide my face fro hem, for Y haue schede out my spirit on al the hous of Israel, seith the Lord God.", "rotherham": "Neither will I any more hide my face from them,— In that I have poured out my spirit, upon the house of Israel, Declareth My Lord Yahweh.", "darby": "And I will not hide my face any more from them, for I shall have poured out my Spirit upon the house of Israel, saith the Lord Jehovah.", "twenty": "", "jps": "neither will I hide My face any more from them; for I have poured out My spirit upon the house of Israel, saith the L-rd GOD.'", "acv": "nor will I hide my face any more from them. For I have poured out my Spirit upon the house of Israel, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And I will hide my face from them no more; for I have poured out my spirit upon the house of Israel, saith the Lord Jehovah.", "webster": "Neither will I hide my face any more from them: for I have poured out my spirit upon the house of Israel, saith the Lord GOD.", "vulgate": "et non abscondam ultra faciem meam ab eis eo quod effuderim spiritum meum super omnem domum Israhel ait Dominus Deus;", "brenton": "And I will no more turn away my face from them, because I have poured out my wrath upon the house of Israel, saith the Lord God."}}]}, {"c": 40, "verses": [{"v": 1, "ref": "40:1", "o": "בְּ/עֶשְׂרִ֣ים וְ/חָמֵ֣שׁ שָׁנָ֣ה לְ֠/גָלוּתֵ/נוּ בְּ/רֹ֨אשׁ הַ/שָּׁנָ֜ה בֶּ/עָשׂ֣וֹר לַ/חֹ֗דֶשׁ בְּ/אַרְבַּ֤ע עֶשְׂרֵה֙ שָׁנָ֔ה אַחַ֕ר אֲשֶׁ֥ר הֻכְּתָ֖ה הָ/עִ֑יר בְּ/עֶ֣צֶם הַ/יּ֣וֹם הַ/זֶּ֗ה הָיְתָ֤ה עָלַ/י֙ יַד יְהוָ֔ה וַ/יָּבֵ֥א אֹתִ֖/י שָֽׁמָּ/ה", "en": {"kjv": "In the five and twentieth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after that the city was smitten, in the selfsame day the hand of the Lord was upon me, and brought me thither.", "web": "In the twenty-fifth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after that the city was struck, in the same day, the hand of Yahweh was on me, and he brought me there.", "bsb": "In the twenty-fifth year of our exile, at the beginning of the year, on the tenth day of the month—in the fourteenth year after Jerusalem had been struck down—on that very day the hand of the LORD was upon me, and He took me there.", "asv": "In the five and twentieth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after that the city was smitten, in the selfsame day, the hand of Jehovah was upon me, and he brought me thither.", "ylt": "In the twenty and fifth year of our removal, in the beginning of the year, in the tenth of the month, in the fourteenth year after that the city was smitten, in this self-same day hath a hand of Jehovah been upon me, and He bringeth me in thither;", "dra": "In the five and twentieth year of our captivity, in the beginning of the year, the tenth day of the month, the fourteenth year after the city was destroyed: in the selfsame day the hand of the Lord was upon me, and he brought me thither.", "bbe": "In the twenty-fifth year after we had been taken away prisoners, in the first month of the year, on the tenth day of the month, in the fourteenth year after the town was taken, on the very same day, the hand of the Lord was on me, and he took me there.", "geneva": "In the fiue and twentieth yeere of our being in captiuitie, in the beginning of the yeere, in the tenth day of the moneth, in the fourteenth yeere after that the citie was smitten, in the selfe same day, the hande of the Lord was vpon mee, and brought me thither.", "wycliffe": "In the fyue and twentithe yeer of oure passyng ouer, in the bigynnyng of the yeer, in the tenthe dai of the monethe, in the fourtenthe yeer after that the citee was smytun, in this same dai the hond of the Lord was maad on me, and he brouyte me thidur in the reuelaciouns of God.", "rotherham": "In the twenty-fifth year of our exile at the beginning of the year. on the tenth of the month in the fourteenth year, after the city was smitten, on this selfsame day, came upon me the hand of Yahweh, and he brought me thither:", "darby": "In the twenty-fifth year of our captivity, in the beginning of the year, on the tenth of the month, in the fourteenth year after that the city was smitten, on that same day the hand of Jehovah was upon me, and he brought me thither.", "twenty": "", "jps": "In the five and twentieth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after that the city was smitten, in the selfsame day, the hand of HaShem was upon me, and He brought me thither.", "acv": "In the twenty-fifth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after the city was smitten, in the selfsame day, the hand of Jehovah was upon me, and he brought me there.", "anderson": "", "haweis": "", "noyes": "In the five and twentieth year of our captivity, in the first month, on the tenth day of the month, in the fourteenth year after that the city was smitten, on the selfsame day the hand of Jehovah was upon me, and he brought me [thither into the city].", "webster": "In the five and twentieth year of our captivity, in the beginning of the year, in the tenth [day] of the month, in the fourteenth year after the city was smitten, in the same day the hand of the LORD was upon me, and brought me thither.", "vulgate": "in vicesimo et quinto anno transmigrationis nostrae in exordio anni decima mensis quartodecimo anno postquam percussa est civitas in ipsa hac die facta est super me manus Domini et adduxit me illuc;", "brenton": "And it came to pass in the twenty-fifth year of our captivity, in the first month, on the tenth day of the month, in the fourteenth year after the taking of the city, in that day the hand of the Lord was upon me, and brought me"}}, {"v": 2, "ref": "40:2", "o": "בְּ/מַרְא֣וֹת אֱלֹהִ֔ים הֱבִיאַ֖/נִי אֶל אֶ֣רֶץ יִשְׂרָאֵ֑ל וַ/יְנִיחֵ֗/נִי אֶל הַ֤ר גָּבֹ֨הַּ֙ מְאֹ֔ד וְ/עָלָ֥י/ו כְּ/מִבְנֵה עִ֖יר מִ/נֶּֽגֶב", "en": {"kjv": "In the visions of God brought he me into the land of Israel, and set me upon a very high mountain, by which was as the frame of a city on the south.", "web": "In the visions of God brought he me into the land of Israel, and set me down on a very high mountain, whereon was as it were the frame of a city on the south.", "bsb": "In visions of God He took me to the land of Israel and set me on a very high mountain, on whose southern slope was a structure that resembled a city.", "asv": "In the visions of God brought he me into the land of Israel, and set me down upon a very high mountain, whereon was as it were the frame of a city on the south.", "ylt": "in visions of God He hath brought me in unto the land of Israel, and causeth me to rest on a very high mountain, and upon it is as the frame of a city on the south.", "dra": "In the visions of God he brought me into the land of Israel, and set me upon a very high mountain: upon which there was as the building of a city, bending towards the south.", "bbe": "In the visions of God he took me into the land of Israel, and put me down on a very high mountain, on which there was, as it seemed, a building like a town opposite me.", "geneva": "Into the lande of Israel brought he me by a diuine vision, and set me vpon a very hie mountaine, whereupon was as the building of a citie, toward the South.", "wycliffe": "And he brouyte me in to the lond of Israel, and he leet me doun on a ful hiy hil, on which was as the bildyng of a citee goynge to the south;", "rotherham": "In the visions of God, he brought me into the land of Israel,—and set me down upon an exceeding high mountain, and thereupon, was, as it were the structure of a city, on the south.", "darby": "In the visions ofGod brought he me into the land of Israel, and set me upon a very high mountain; and upon it was as the building of a city, on the south.", "twenty": "", "jps": "In the visions of G-d brought He me into the land of Israel, and set me down upon a very high mountain, whereon was as it were the frame of a city on the south.", "acv": "He brought me in the visions of God into the land of Israel, and set me down upon a very high mountain, upon which was as it were the frame of a city on the south.", "anderson": "", "haweis": "", "noyes": "In the visions of God he brought me into the land of Israel, and set me upon a very high mountain, upon which was, as it were, the frame of a city toward the south.", "webster": "In the visions of God he brought me into the land of Israel, and set me upon a very high mountain, by which [was] as the frame of a city on the south.", "vulgate": "in visionibus Dei adduxit me in terram Israhel et dimisit me super montem excelsum nimis super quem erat quasi aedificium civitatis vergentis ad austrum;", "brenton": "in a vision of God into the land of Israel, and set me on a very high mountain, and upon it there was as it were the frame of a city before me."}}, {"v": 3, "ref": "40:3", "o": "וַ/יָּבֵ֨יא אוֹתִ֜/י שָׁ֗מָּ/ה וְ/הִנֵּה אִישׁ֙ מַרְאֵ֨/הוּ֙ כְּ/מַרְאֵ֣ה נְחֹ֔שֶׁת וּ/פְתִיל פִּשְׁתִּ֥ים בְּ/יָד֖/וֹ וּ/קְנֵ֣ה הַ/מִּדָּ֑ה וְ/ה֥וּא עֹמֵ֖ד בַּ/שָּֽׁעַר", "en": {"kjv": "And he brought me thither, and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.", "web": "He brought me there; and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.", "bsb": "So He took me there, and I saw a man whose appearance was like bronze. He was standing in the gateway with a linen cord and a measuring rod in his hand.", "asv": "And he brought me thither; and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.", "ylt": "And He bringeth me in thither, and lo, a man, his appearance as the appearance of brass, and a thread of flax in his hand, and a measuring-reed, and he is standing at the gate,", "dra": "And he brought me in thither, and behold a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed in his hand, and he stood in the gate.", "bbe": "He took me there, and I saw a man, looking like brass, with a linen cord in his hand and a measuring rod: and he was stationed in the doorway.", "geneva": "And he brought me thither, and beholde, there was a man, whose similitude was to looke to, like brasse, with a linnen thread in his hand, and a reede to measure with: and he stoode at the gate.", "wycliffe": "and he ledde me in thidur. And lo! a man, whos licnesse was as the licnesse of bras, and a coorde of flex was in his hond, and a reed of mesure in his hond; forsothe he stood in the yate.", "rotherham": "And when he brought me thither, then lo! a man whose appearance was like the appearance of bronze, with a flax-cord in his hand and measuring reed,—and he was standing in the gate.", "darby": "And he brought me thither, and behold, there was a man whose appearance was like the appearance of brass, with a flax-cord in his hand, and a measuring-reed; and he stood in the gate.", "twenty": "", "jps": "And He brought me thither, and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.", "acv": "And he brought me there, and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed. And he stood in the gate.", "anderson": "", "haweis": "", "noyes": "And when he had brought me thither, behold, there was a man, whose appearance was as the appearance of brass, with a line of flax in his hand, and a measuring-reed, and he stood in the gate.", "webster": "And he brought me thither, and behold, [there was] a man, whose appearance [was] like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.", "vulgate": "et introduxit me illuc et ecce vir cuius erat species quasi species aeris et funiculus lineus in manu eius et calamus mensurae in manu eius stabat autem in porta;", "brenton": "And he brought me in thither, and, behold, there was a man, and the appearance of him was as the appearance of shining brass, and in his hand was a builder's line, and a measuring reed; and he stood at the gate."}}, {"v": 4, "ref": "40:4", "o": "וַ/יְדַבֵּ֨ר אֵלַ֜/י הָ/אִ֗ישׁ בֶּן אָדָ֡ם רְאֵ֣ה בְ/עֵינֶי/ךָ֩ וּ/בְ/אָזְנֶ֨י/ךָ שְּׁמָ֜ע וְ/שִׂ֣ים לִבְּ/ךָ֗ לְ/כֹ֤ל אֲשֶׁר אֲנִי֙ מַרְאֶ֣ה אוֹתָ֔/ךְ כִּ֛י לְמַ֥עַן הַרְאוֹתְ/כָ֖ה הֻבָ֣אתָה הֵ֑נָּה הַגֵּ֛ד אֶת כָּל אֲשֶׁר אַתָּ֥ה רֹאֶ֖ה לְ/בֵ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "And the man said unto me, Son of man, behold with thine eyes, and hear with thine ears, and set thine heart upon all that I shall shew thee; for to the intent that I might shew them unto thee art thou brought hither: declare all that thou seest to the house of Israel.", "web": "The man said to me, Son of man, see with your eyes, and hear with your ears, and set your heart on all that I shall show you; for, to the intent that I may show them to you, you are brought here: declare all that you see to the house of Israel.", "bsb": "“Son of man,” he said to me, “look with your eyes, hear with your ears, and pay attention to everything I am going to show you, for that is why you have been brought here. Report to the house of Israel everything you see.”", "asv": "And the man said unto me, Son of man, behold with thine eyes, and hear with thine ears, and set thy heart upon all that I shall show thee; for, to the intent that I may show them unto thee, art thou brought hither: declare all that thou seest to the house of Israel.", "ylt": "and the man speaketh unto me: `Son of man, see with thine eyes, And with thine ears hear, And set thy heart to all that I am shewing thee, For, in order to shew it thee, Thou hast been brought in hither, Declare all that thou art seeing to the house of Israel.'", "dra": "And this man said to me: Son of man, see with thy eyes, and hear with thy ears, and set thy heart upon all that I shall shew thee: for thou art brought hither that they may be shewn to thee: declare all that thou seest, to the house of Israel.", "bbe": "And the man said to me, Son of man, see with your eyes and give hearing with your ears, and take to heart everything I am going to let you see; for in order that I might let you see them, you have come here: and give an account of all you see to the children of Israel.", "geneva": "And the man said vnto me, Sonne of man, beholde with thine eyes, and heare with thine eares, and set thine heart vpon all that I shall shew thee: for to the intent, that they might be shewed thee, art thou brought hither: declare al that thou seest, vnto the house of Israel.", "wycliffe": "And the same man spak to me, Thou sone of man, se with thin iyen, and here with thin eeris, and sette thin herte on alle thingis, whiche Y schal schewe to thee, for thou art brouyt hidur, that tho be schewid to thee; telle thou alle thingis whiche thou seest to the hous of Israel.", "rotherham": "And the man spake unto me, saying. Son of man See with thine eyes And with thine ears, hear thou And apply thy heart to whatsoever I am about to show thee, For to the intent it might be shown thee, hast thou been brought hither,- Declare all that thou seest unto the house of Israel.", "darby": "And the man said unto me, Son of man, behold with thine eyes, and hear with thine ears, and set thy heart upon all that I shall shew thee; for in order that it might be shewn unto thee art thou brought hither. Declare to the house of Israel all that thou seest.", "twenty": "", "jps": "And the man said unto me: 'Son of man, behold with thine eyes, and hear with thine ears, and set thy heart upon all that I shall show thee, for to the intent that I might show them unto thee art thou brought thither; declare all that thou seest to the house of Israel.'", "acv": "And the man said to me, Son of man, behold with thine eyes, and hear with thine ears, and set thy heart upon all that I shall show thee. For thou are brought here to the intent that I may show them to thee. Declare all that thou see to the house of Israel.", "anderson": "", "haweis": "", "noyes": "And the man said to me, Son of man, behold with thine eyes and hear with thine ears, and give heed to all which I shall show thee; for to the intent that I might show them to thee art thou brought hither; declare all which thou seest to the house of Israel!", "webster": "And the man said to me, Son of man, behold with thy eyes, and hear with thy ears, and set thy heart upon all that I shall show thee; for, to the intent that I might show [them] to thee [art] thou brought hither: declare all that thou seest to the house of Israel.", "vulgate": "et locutus est ad me idem vir fili hominis vide oculis tuis et auribus tuis audi et pone cor tuum in omnia quae ego ostendam tibi quia ut ostendantur tibi adductus es huc adnuntia omnia quae tu vides domui Israhel;", "brenton": "And the man said to me, Look with thine eyes at him whom thou hast seen, son of man, and hear with thine ears, and lay up in thine heart all things that I show thee; for thou hast come in hither that I might show thee, and thou shalt show all things that thou seest to the house of Israel."}}, {"v": 5, "ref": "40:5", "o": "וְ/הִנֵּ֥ה חוֹמָ֛ה מִ/ח֥וּץ לַ/בַּ֖יִת סָבִ֣יב סָבִ֑יב וּ/בְ/יַ֨ד הָ/אִ֜ישׁ קְנֵ֣ה הַ/מִּדָּ֗ה שֵׁשׁ אַמּ֤וֹת בָּֽ/אַמָּה֙ וָ/טֹ֔פַח וַ/יָּ֜מָד אֶת רֹ֤חַב הַ/בִּנְיָן֙ קָנֶ֣ה אֶחָ֔ד וְ/קוֹמָ֖ה קָנֶ֥ה אֶחָֽד", "en": {"kjv": "And behold a wall on the outside of the house round about, and in the man’s hand a measuring reed of six cubits long by the cubit and an hand breadth: so he measured the breadth of the building, one reed; and the height, one reed.", "web": "Behold, a wall on the outside of the house all around, and in the man’s hand a measuring reed six cubits long, of a cubit and a hand breadth each: so he measured the thickness of the building, one reed; and the height, one reed.", "bsb": "And I saw a wall surrounding the temple area. Now the length of the measuring rod in the man’s hand was six long cubits (each measuring a cubit and a handbreadth), and he measured the wall to be one rod thick and one rod high.", "asv": "And, behold, a wall on the outside of the house round about, and in the man’s hand a measuring reed six cubits long, of a cubit and a handbreadth each: so he measured the thickness of the building, one reed; and the height, one reed.", "ylt": "And lo, a wall on the outside of the house all round about, and in the hand of the man a measuring-reed, six cubits by a cubit and a handbreadth, and he measureth the breadth of the building one reed, and the height one reed.", "dra": "And behold there was a wall on the outside of the house round about, and in the man's hand a measuring reed of six cubits and a handbreadth: and he measured the breadth of the building one reed, and the height one reed.", "bbe": "And there was a wall on the outside of the house all round, and in the man's hand there was a measuring rod six cubits long by a cubit and a hand's measure: so he took the measure of the building from side to side, one rod; and from base to top, one rod.", "geneva": "And beholde, I sawe a wall on the outside of the house round about: and in the mans hand was a reede to measure with, of sixe cubites long, by the cubite, and an hand breadth: so he measured the breadth of the buylding with one reede, and the height with one reede.", "wycliffe": "And lo! a wal withouteforth, in the cumpas of the hous on ech side; and in the hond of the man was a rehed of mesure of sixe cubitis and a spanne, that is, an handibreede; and he mat the breede of the bildyng with o rehed, and the hiynesse bi o rehed.", "rotherham": "And lo a wall on the outside of the house round about on every side,—and in the hand of the man, was the measuring reed six cubits by the cubit, and a handbreadth, so he measured the breadth of the enclosing-wall, one reed, and the height one reed.", "darby": "And behold, there was a wall on the outside of the house round about, and in the man's hand a measuring-reed of six cubits, [each] of one cubit and a hand breadth. And he measured the breadth of the building, one reed; and the height, one reed.", "twenty": "", "jps": "And behold a wall on the outside of the house round about, and in the man's hand a measuring reed of six cubits long, of a cubit and a hand-breadth each; so he measured the breadth of the building, one reed, and the height, one reed.", "acv": "And, behold, a wall on the outside of the house round about, and in the man's hand a measuring reed six cubits long, of a cubit and a handbreadth each. So he measured the thickness of the building, one reed, and the height, one reed.", "anderson": "", "haweis": "", "noyes": "And behold, a wall on the outside of the house round about, and in the man’s hand a measuring reed, in length six cubits of a cubit and a handbreadth; and he measured the breadth of the wall, one reed; and the height, one reed.", "webster": "And behold a wall on the outside of the house around, and in the man's hand a measuring reed of six cubits [long] by the cubit and a hand-breadth: so he measured the breadth of the building, one reed: and the hight, one reed.", "vulgate": "et ecce murus forinsecus in circuitu domus undique et in manu viri calamus mensurae sex cubitorum et palmo et mensus est latitudinem aedificii calamo uno altitudinem quoque calamo uno;", "brenton": "And behold a wall round about the house without, and in the man's hand a reed, the measure of it was six cubits by the cubit, and a span: and he measured across the front wall; the breadth was equal to the reed, and the length of it equal to the reed."}}, {"v": 6, "ref": "40:6", "o": "וַ/יָּב֗וֹא אֶל שַׁ֨עַר֙ אֲשֶׁ֤ר פָּנָי/ו֙ דֶּ֣רֶךְ הַ/קָּדִ֔ימָ/ה וַ/יַּ֖עַל ב/מעלות/ו בְּ/מַֽעֲלוֹתָ֑י/ו וַ/יָּ֣מָד אֶת סַ֣ף הַ/שַּׁ֗עַר קָנֶ֤ה אֶחָד֙ רֹ֔חַב וְ/אֵת֙ סַ֣ף אֶחָ֔ד קָנֶ֥ה אֶחָ֖ד רֹֽחַב", "en": {"kjv": "Then came he unto the gate which looketh toward the east, and went up the stairs thereof, and measured the threshold of the gate, which was one reed broad; and the other threshold of the gate, which was one reed broad.", "web": "Then came he to the gate which looks toward the east, and went up its steps: and he measured the threshold of the gate, one reed broad; and the other threshold, one reed broad.", "bsb": "Then he came to the gate facing east and climbed its steps. He measured the threshold of the gate to be one rod deep.", "asv": "Then came he unto the gate which looketh toward the east, and went up the steps thereof: and he measured the threshold of the gate, one reed broad; and the other threshold, one reed broad.", "ylt": "And he cometh in unto the gate whose front is eastward, and he goeth up by its steps, and he measureth the threshold of the gate one reed broad, even the one threshold one reed broad,", "dra": "And he came to the gate that looked toward the east, and he went up the steps thereof: and he measured the breadth of the threshold of the gate one reed, that is, one threshold was one reed broad;", "bbe": "Then he came to the doorway looking to the east, and went up by its steps; and he took the measure of the doorstep, one rod wide.", "geneva": "Then came he vnto the gate, which looketh towarde the East, and went vp the stayres thereof, and measured the poste of the gate, which was one reede broade, and the other poste of the gate, which was one reede broade.", "wycliffe": "And he cam to the yate that bihelde the weie of the eest, and he stiede bi degrees of it; and he mat the lyntil of the yate bi o rehed the breede, that is, o lyntil bi o rehed in breede;", "rotherham": "Then came he unto the gate that looked toward the east, and went up by the steps thereof,—and measured the threshold of the gate one reed broad, and the other threshold one reed broad.", "darby": "And he came to the gate which looked toward the east, and went up its steps; and he measured the threshold of the gate, one reed broad; and the other threshold one reed broad.", "twenty": "", "jps": "Then came he unto the gate which looketh toward the east, and went up the steps thereof; and he measured the jamb of the gate, one reed broad, and the other jamb, one reed broad.", "acv": "Then he came to the gate which looks toward the east, and went up the steps of it. And he measured the threshold of the gate, one reed broad, and the other threshold, one reed broad.", "anderson": "", "haweis": "", "noyes": "Then came he to the gate, which looked toward the east, and went up the steps thereof, and measured the upper threshold of the gate, one reed broad, and the other threshold of the gate one reed broad.", "webster": "Then he came to the gate which looketh towards the east, and ascended its stairs, and measured the threshhold of the gate, [which was] one reed broad; and the other threshhold [of the gate], [which was] one reed broad.", "vulgate": "et venit ad portam quae respiciebat viam orientalem et ascendit per gradus eius et mensus est limen portae calamo uno latitudinem id est limen unum calamo uno in latitudine;", "brenton": "And he entered by seven steps into the gate that looks eastward, and he measured across the porch of the gate equal to the reed."}}, {"v": 7, "ref": "40:7", "o": "וְ/הַ/תָּ֗א קָנֶ֨ה אֶחָ֥ד אֹ֨רֶךְ֙ וְ/קָנֶ֤ה אֶחָד֙ רֹ֔חַב וּ/בֵ֥ין הַ/תָּאִ֖ים חָמֵ֣שׁ אַמּ֑וֹת וְ/סַ֣ף הַ֠/שַּׁעַר מֵ/אֵ֨צֶל אוּלָ֥ם הַ/שַּׁ֛עַר מֵֽ/הַ/בַּ֖יִת קָנֶ֥ה אֶחָֽד", "en": {"kjv": "And every little chamber was one reed long, and one reed broad; and between the little chambers were five cubits; and the threshold of the gate by the porch of the gate within was one reed.", "web": "Every lodge was one reed long, and one reed broad; and between the lodges was five cubits; and the threshold of the gate by the porch of the gate toward the house was one reed.", "bsb": "Each gate chamber was one rod long and one rod wide, and there were five cubits between the gate chambers. The inner threshold of the gate by the portico facing inward was one rod deep.", "asv": "And every lodge was one reed long, and one reed broad; and the space between the lodges was five cubits; and the threshold of the gate by the porch of the gate toward the house was one reed.", "ylt": "and the little chamber one reed long and one reed broad, and between the little chambers five cubits, and the threshold of the gate, from the side of the porch of the gate from within, one reed.", "dra": "And every little chamber was one reed long, and one reed broad: and between the little chambers were five cubits:", "bbe": "And the watchmen's rooms were one rod long and one rod wide; and the space between the rooms was five cubits; the doorstep of the doorway, by the covered way of the doorway inside, was one rod.", "geneva": "And euery chamber was one reede long, and one reede broad, and betweene the chambers were fiue cubites: and the post of the gate by the porch of the gate within was one reede.", "wycliffe": "and he mat o chaumbre bi o rehed in lengthe, and bi o rehed in breed, and fyue cubitis bitwixe chaumbris;", "rotherham": "And the lodge was one reed long, and one reed broad, and between the lodges, was a space of five cubits,—and the threshold of the gate from beside the porch of the gate inwards, was one reed.", "darby": "And [each] chamber was one reed long and one reed broad; and between the chambers were five cubits; and the threshold of the gate, beside the porch of the gate within, was one reed.", "twenty": "", "jps": "And every cell was one reed long, and one reed broad; and the space between the cells was five cubits; and the jambs of the gate by the porch of the gate within were one reed.", "acv": "And every little chamber was one reed long, and one reed broad, and the space between the little chambers was five cubits. And the threshold of the gate by the porch of the gate toward the house was one reed.", "anderson": "", "haweis": "", "noyes": "And every chamber was one reed long, and one reed broad; and between the chambers were five cubits; and the threshold of the gate by the porch of the gate within was one reed.", "webster": "And [every] little chamber [was] one reed long, and one reed broad; and between the little chambers [were] five cubits; and the threshhold of the gate by the porch of the gate within [was] one reed.", "vulgate": "et thalamum uno calamo in longum et uno calamo in latum et inter thalamos quinque cubitos;", "brenton": "And the chamber was equal in length to the reed, and equal in breadth to the reed; and the porch between the chambers six cubits; and the second chamber equal in breadth to the reed, and equal in length to the reed, and the porch five cubits."}}, {"v": 8, "ref": "40:8", "o": "וַ/יָּ֜מָד אֶת אֻלָ֥ם הַ/שַּׁ֛עַר מֵ/הַ/בַּ֖יִת קָנֶ֥ה אֶחָֽד", "en": {"kjv": "He measured also the porch of the gate within, one reed.", "web": "He measured also the porch of the gate toward the house, one reed.", "bsb": "Then he measured the portico of the gateway inside;", "asv": "He measured also the porch of the gate toward the house, one reed.", "ylt": "And he measureth the porch of the gate from within one reed,", "dra": "And the threshold of the gate by the porch of the gate within, was one reed.", "bbe": "And he took the measure of the covered way of the doorway inside,", "geneva": "He measured also the porche of the gate within with one reede.", "wycliffe": "and he mat the lyntil of the yate bisidis the porche of the yate with ynne, bi o rehed.", "rotherham": "Then measured he the porch of the gate inwards, one reed.", "darby": "And he measured the porch of the gate within, one reed.", "twenty": "", "jps": "He measured also the porch of the gate toward the house, one reed.", "acv": "He also measured the porch of the gate toward the house, one reed.", "anderson": "", "haweis": "", "noyes": "He measured also the porch of the gate within, one reed.", "webster": "He measured also the porch of the gate within, one reed.", "vulgate": "et limen portae iuxta vestibulum portae intrinsecus calamo uno;", "brenton": "And the third chamber equal in length to the reed, and equal in breadth to the reed."}}, {"v": 9, "ref": "40:9", "o": "וַ/יָּ֜מָד אֶת אֻלָ֤ם הַ/שַּׁ֨עַר֙ שְׁמֹנֶ֣ה אַמּ֔וֹת ו/איל/ו וְ/אֵילָ֖י/ו שְׁתַּ֣יִם אַמּ֑וֹת וְ/אֻלָ֥ם הַ/שַּׁ֖עַר מֵ/הַ/בָּֽיִת", "en": {"kjv": "Then measured he the porch of the gate, eight cubits; and the posts thereof, two cubits; and the porch of the gate was inward.", "web": "Then measured he the porch of the gate, eight cubits; and its posts, two cubits; and the porch of the gate was toward the house.", "bsb": "it was eight cubits deep, and its jambs were two cubits thick. And the portico of the gateway faced the temple.", "asv": "Then measured he the porch of the gate, eight cubits; and the posts thereof, two cubits; and the porch of the gate was toward the house.", "ylt": "and he measureth the porch of the gate eight cubits, and its posts two cubits, and the porch of the gates from within,", "dra": "And he measured the porch of the gate eight cubits, and the front thereof two cubits: and the porch of the gate was inward.", "bbe": "Eight cubits; and its uprights, two cubits; the covered way of the doorway was inside.", "geneva": "Then measured he the porch of the gate of eight cubites, and the postes thereof, of two cubites, and the porch of the gate was inward.", "wycliffe": "And he mat the porch of the yate of eiyte cubitis, and the frount therof bi twei cubitis; sotheli the porche of the yate was with ynne.", "rotherham": "Then measured he the porch of the gate, eight cubits, and the projections thereof two cubits,—and the porch of the gate was within,", "darby": "And he measured the porch of the gate, eight cubits; and the posts thereof, two cubits; and the porch of the gate was inward.", "twenty": "", "jps": "Then measured he the porch of the gate, eight cubits; and the posts thereof, two cubits; and the porch of the gate was inward.", "acv": "Then he measured the porch of the gate, eight cubits, and the posts thereof, two cubits. And the porch of the gate was toward the house.", "anderson": "", "haweis": "", "noyes": "Then he measured the porch of the gate, eight cubits; and the border thereof, two cubits; now the porch of the gate was inward.", "webster": "Then he measured the porch of the gate, eight cubits; and its posts, two cubits; and the porch of the gate [was] inward.", "vulgate": "et mensus est vestibulum portae octo cubitorum et frontem eius duobus cubitis vestibulum autem portae erat intrinsecus;", "brenton": "And the porch of the gateway (near the porch of the gate) eight cubits; and the posts there of two cubits; and the porch of the gate was inward:"}}, {"v": 10, "ref": "40:10", "o": "וְ/תָאֵ֨י הַ/שַּׁ֜עַר דֶּ֣רֶךְ הַ/קָּדִ֗ים שְׁלֹשָׁ֤ה מִ/פֹּה֙ וּ/שְׁלֹשָׁ֣ה מִ/פֹּ֔ה מִדָּ֥ה אַחַ֖ת לִ/שְׁלָשְׁתָּ֑/ם וּ/מִדָּ֥ה אַחַ֛ת לָ/אֵילִ֖ם מִ/פֹּ֥ה וּ/מִ/פּֽוֹ", "en": {"kjv": "And the little chambers of the gate eastward were three on this side, and three on that side; they three were of one measure: and the posts had one measure on this side and on that side.", "web": "The lodges of the gate eastward were three on this side, and three on that side; they three were of one measure: and the posts had one measure on this side and on that side.", "bsb": "There were three gate chambers on each side of the east gate, each with the same measurements, and the gateposts on either side also had the same measurements.", "asv": "And the lodges of the gate eastward were three on this side, and three on that side; they three were of one measure: and the posts had one measure on this side and on that side.", "ylt": "and the little chambers of the gate eastward, three on this side, and three on that side; one measure is to them three, and one measure is to the posts, on this side and on that side.", "dra": "And the little chambers of the gate that looked eastward were three on this side, and three on that side: all three were of one measure, and the fronts of one measure, on both parts.", "bbe": "And the rooms of the doorway on the east were three on this side and three on that; all three were of the same size; and the uprights on this side and on that were of the same size.", "geneva": "And the chambers of the gate Eastwarde, were three on this side, and three on that side: they three were of one measure, and the postes had one measure on this side, and one on that side.", "wycliffe": "Certis the chaumbris of the yate at the weie of the eest weren thre on this side, and thre on that side; o mesure of thre, and o mesure of the frountis on euer ethir side.", "rotherham": "And, the lodges of the gate that was towards the east, were three on this side and three on that side, one measure, had they three,—and one measure, had the projections on this side and on that side.", "darby": "And the chambers of the gate which was toward the east were three on this side and three on that side: they three were of one measure; and the posts on this side and on that side had one measure.", "twenty": "", "jps": "And the cells of the gate eastward were three on this side, and three on that side; they three were of one measure; and the posts had one measure on this side and on that side.", "acv": "And the little chambers of the gate eastward were three on this side, and three on that side; those three were of one measure. And the posts had one measure on this side and on that side.", "anderson": "", "haweis": "", "noyes": "And the chambers of the gate eastward were three on this side, and three on that side; they three were of one measure, and the projecting wall-pillars were of one measure on this side, and on that side.", "webster": "And the little chambers of the gate eastward [were] three on this side, and three on that side; they three [were] of one measure: and the posts had one measure on this side and on that side.", "vulgate": "porro thalami portae ad viam orientalem tres hinc et tres inde mensura una trium et mensura una frontium ex utraque parte;", "brenton": "and the chambers of the gate of the chamber in front were three on one side and three on the other, and there was one measure to the three: there was one measure to the porches on this side and on that."}}, {"v": 11, "ref": "40:11", "o": "וַ/יָּ֛מָד אֶת רֹ֥חַב פֶּֽתַח הַ/שַּׁ֖עַר עֶ֣שֶׂר אַמּ֑וֹת אֹ֣רֶךְ הַ/שַּׁ֔עַר שְׁל֥וֹשׁ עֶשְׂרֵ֖ה אַמּֽוֹת", "en": {"kjv": "And he measured the breadth of the entry of the gate, ten cubits; and the length of the gate, thirteen cubits.", "web": "He measured the breadth of the opening of the gate, ten cubits; and the length of the gate, thirteen cubits;", "bsb": "And he measured the width of the gateway entrance to be ten cubits, and its length was thirteen cubits.", "asv": "And he measured the breadth of the opening of the gate, ten cubits; and the length of the gate, thirteen cubits;", "ylt": "And he measureth the breadth of the opening of the gate ten cubits, the length of the gate thirteen cubits;", "dra": "And he measured the breadth of the threshold of the gate ten cubits: and the length of the gate thirteen cubits:", "bbe": "And he took the measure of the opening of the doorway, ten cubits wide; and the way down the doorway was thirteen cubits;", "geneva": "And he measured the breadth of the entrie of the gate ten cubites, and the height of the gate thirteene cubites.", "wycliffe": "And he mat the breede of the lyntel of the yate of ten cubitis, and the lengthe of the yate of threttene cubitis.", "rotherham": "Then measured he the breadth of the entrance of the gate, ten cubits—the length of the gate, thirteen cubits,", "darby": "And he measured the breadth of the entry of the gate, ten cubits; [and] the length of the gate, thirteen cubits.", "twenty": "", "jps": "And he measured the breadth of the entry of the gate, ten cubits; and the length of the gate, thirteen cubits;", "acv": "And he measured the breadth of the opening of the gate, ten cubits, and the length of the gate, thirteen cubits,", "anderson": "", "haweis": "", "noyes": "And he measured the breadth of the entry of the gate, ten cubits; and the length of the entry of the gate, thirteen cubits.", "webster": "And he measured the breadth of the entry of the gate, ten cubits; [and] the length of the gate, thirteen cubits.", "vulgate": "et mensus est latitudinem liminis portae decem cubitorum et longitudinem portae tredecim cubitorum;", "brenton": "And he measured the breadth of the door of the gateway, ten cubits; and the breadth of the gateway thirteen cubits."}}, {"v": 12, "ref": "40:12", "o": "וּ/גְב֞וּל לִ/פְנֵ֤י הַ/תָּאוֹת֙ אַמָּ֣ה אֶחָ֔ת וְ/אַמָּה אַחַ֥ת גְּב֖וּל מִ/פֹּ֑ה וְ/הַ/תָּ֕א שֵׁשׁ אַמּ֣וֹת מִ/פּ֔וֹ וְ/שֵׁ֥שׁ אַמּ֖וֹת מִ/פּֽוֹ", "en": {"kjv": "The space also before the little chambers was one cubit on this side, and the space was one cubit on that side: and the little chambers were six cubits on this side, and six cubits on that side.", "web": "and a border before the lodges, one cubit on this side, and a border, one cubit on that side; and the lodges, six cubits on this side, and six cubits on that side.", "bsb": "In front of each gate chamber was a wall one cubit high, and the gate chambers were six cubits square.", "asv": "and a border before the lodges, one cubit on this side, and a border, one cubit on that side; and the lodges, six cubits on this side, and six cubits on that side.", "ylt": "and a border before the little chambers, one cubit, and one cubit is the border on this side, and the little chamber is six cubits on this side, and six cubits on that side.", "dra": "And the border before the little chambers one cubit: and one cubit was the border on both sides: and the little chambers were six cubits on this side and that side.", "bbe": "And the space in front of the rooms, a cubit on this side and a cubit on that side; and the rooms six cubits on this side and six cubits on that.", "geneva": "The space also before the chambers was one cubite on this side, and the space was one cubite on that side, and the chambers were sixe cubites on this side and sixe cubites on that side.", "wycliffe": "And he mat a margyn of a cubit bifor the chaumbris, and o cubit was the ende on ech side; forsothe the chaumbris weren of sixe cubitis on this side and on that side.", "rotherham": "And the space before the lodges was one cubit, and one cubit, the space on that side; and the lodge itself was six cubits on this side, and six cubits on that side.", "darby": "And there was a border before the chambers of one cubit, and a border of one cubit on the other side; and the chambers were six cubits on this side, and six cubits on that side.", "twenty": "", "jps": "and a border before the cells, one cubit on this side, and a border, one cubit on that side; and the cells, six cubits on this side, and six cubits on that side.", "acv": "and a border before the little chambers, one cubit on this side, and a border, one cubit on that side, and the little chambers, six cubits on this side, and six cubits on that side.", "anderson": "", "haweis": "", "noyes": "There was also a space before the chambers one cubit on this side, and a space one cubit on that side; and every chamber was six cubits on this side, and six cubits on that side.", "webster": "The space also before the little chambers [was] one cubit [on this side], and the space [was] one cubit on that side: and the little chambers [were] six cubits on this side, and six cubits on that side.", "vulgate": "et marginem ante thalamos cubiti unius et cubitus unus finis utrimque thalami autem sex cubitorum erant hinc et inde;", "brenton": "And the space before the chambers was narrowed to a cubit in front of the chambers on this side and on that side: and the chamber was six cubits this way, and six cubits that way."}}, {"v": 13, "ref": "40:13", "o": "וַ/יָּ֣מָד אֶת הַ/שַּׁ֗עַר מִ/גַּ֤ג הַ/תָּא֙ לְ/גַגּ֔/וֹ רֹ֕חַב עֶשְׂרִ֥ים וְ/חָמֵ֖שׁ אַמּ֑וֹת פֶּ֖תַח נֶ֥גֶד פָּֽתַח", "en": {"kjv": "He measured then the gate from the roof of one little chamber to the roof of another: the breadth was five and twenty cubits, door against door.", "web": "He measured the gate from the roof of the one lodge to the roof of the other, a breadth of twenty-five cubits; door against door.", "bsb": "Then he measured the gateway from the roof of one gate chamber to the roof of the opposite one; the distance was twenty-five cubits from doorway to doorway.", "asv": "And he measured the gate from the roof of the one lodge to the roof of the other, a breadth of five and twenty cubits; door against door.", "ylt": "And he measureth the gate from the roof of the one little chamber to the roof of another; the breadth twenty and five cubits, opening over-against opening.", "dra": "And he measured the gate from the roof of one little chamber to the roof of another, in breadth five and twenty cubits: door against door.", "bbe": "And he took the measure of the doorway from the back of one room to the back of the other, twenty-five cubits across, from door to door.", "geneva": "He measured then the gate from the roufe of a chamber to the toppe of the gate: the breadth was fiue and twentie cubites, doore against doore.", "wycliffe": "And he mat the yate fro the roof of the chaumbre til to the roof therof, the breede of fyue and twenti cubitis, a dore ayens a dore.", "rotherham": "Then measured he the gate, from the roof of this lodge to the roof of that, a breadth of twenty-five cubits,—entrance over against entrance.", "darby": "And he measured the gate from the roof of [one] chamber to the roof [of the other], a breadth of five and twenty cubits, entry opposite entry.", "twenty": "", "jps": "And he measured the gate from the roof of the one cell to the roof of the other, a breadth of five and twenty cubits; door against door.", "acv": "And he measured the gate from the roof of the one little chamber to the roof of the other, a breadth of twenty-five cubits, door against door.", "anderson": "", "haweis": "", "noyes": "Then he measured the gate from the roof of one chamber to the roof of another; the breadth was five and twenty cubits, and door was over against door.", "webster": "He measured then the gate from the roof of [one] little chamber to the roof of another: the breadth [was] five and twenty cubits, door against door.", "vulgate": "et mensus est portam a tecto thalami usque ad tectum eius latitudinem viginti et quinque cubitorum ostium contra ostium;", "brenton": "And he measured the gate from the wall of one chamber to the wall of the other chamber: the breadth was twenty-five cubits, the one gate over against the other gate."}}, {"v": 14, "ref": "40:14", "o": "וַ/יַּ֥עַשׂ אֶת אֵילִ֖ים שִׁשִּׁ֣ים אַמָּ֑ה וְ/אֶל אֵיל֙ הֶֽ/חָצֵ֔ר הַ/שַּׁ֖עַר סָבִ֥יב סָבִֽיב", "en": {"kjv": "He made also posts of threescore cubits, even unto the post of the court round about the gate.", "web": "He made also posts, sixty cubits; and the court reached to the posts, around the gate.", "bsb": "Next he measured the gateposts to be sixty cubits high. The gateway extended around to the gatepost of the courtyard.", "asv": "He made also posts, threescore cubits; and the court reached unto the posts, round about the gate.", "ylt": "And he maketh the posts of sixty cubits, even unto the post of the court, the gate all round about;", "dra": "He made also fronts of sixty cubits: and to the front the court of the gate on every side round about.", "bbe": "And he took the measure of the covered way, twenty cubits; and opening from the covered way of the doorway was the open square round about.", "geneva": "He made also postes of threescore cubites, and the postes of the court, and of the gate had one measure round about.", "wycliffe": "And he made frountes bi sixti cubitis, and at the frount an halle of the yate on ech side bi cumpas;", "rotherham": "Then measured he the porch, twenty cubits,—even unto the projection of the court, the lodges of the gate round about on every side;", "darby": "And he made posts, sixty cubits, and by the post was the court of the gate round about.", "twenty": "", "jps": "He made also posts of threescore cubits; even unto the posts of the court in the gates round about.", "acv": "He also made posts, sixty cubits. And the court reached to the posts, round about the gate.", "anderson": "", "haweis": "", "noyes": "He made also wall-pillars sixty cubits, and toward the pillars, was the court of the gate round about on every side.", "webster": "He made also posts of sixty cubits; even to the post of the court around the gate.", "vulgate": "et fecit frontes per sexaginta cubitos et ad frontem atrium portae undique per circuitum;", "brenton": "And the open space of the porch of the gate without, was twenty cubits to the chambers round about the gate."}}, {"v": 15, "ref": "40:15", "o": "וְ/עַ֗ל פְּנֵי֙ הַ/שַּׁ֣עַר ה/יאתון הָֽ/אִית֔וֹן עַל לִ/פְנֵ֕י אֻלָ֥ם הַ/שַּׁ֖עַר הַ/פְּנִימִ֑י חֲמִשִּׁ֖ים אַמָּֽה", "en": {"kjv": "And from the face of the gate of the entrance unto the face of the porch of the inner gate were fifty cubits.", "web": "From the forefront of the gate at the entrance to the forefront of the inner porch of the gate were fifty cubits.", "bsb": "And the distance from the entrance of the gateway to the far end of its inner portico was fifty cubits.", "asv": "And from the forefront of the gate at the entrance unto the forefront of the inner porch of the gate were fifty cubits.", "ylt": "and by the front of the gate of the entrance, by the front of the porch of the inner gate, fifty cubits;", "dra": "And before the face of the gate which reached even to the face of the porch of the inner gate, fifty cubits.", "bbe": "And from before the opening of the doorway to before the inner covered way of the doorway was fifty cubits.", "geneva": "And vpon the forefront of the entry of the gate vnto the forefront of the porch of the gate within were fiftie cubites.", "wycliffe": "and bifor the face of the yate that stretchith forth til to the face of the porche of the ynner yate, he mat fifti cubitis.", "rotherham": "and, from the face of the gate outwards, unto the face of the porch of the inner gate, was fifty cubits.", "darby": "And from the front of the gate of the entrance unto the front of the porch of the inner gate were fifty cubits.", "twenty": "", "jps": "And from the forefront of the gate of the entrance unto the forefront of the inner porch of the gate were fifty cubits.", "acv": "And from the forefront of the gate at the entrance to the forefront of the inner porch of the gate were fifty cubits.", "anderson": "", "haweis": "", "noyes": "And from the front of the gate of the entrance to the front of the porch of the inner gate were fifty cubits.", "webster": "And from the face of the gate of the entrance to the face of the porch of the inner gate [were] fifty cubits.", "vulgate": "et ante faciem portae quae pertingebat usque ad faciem vestibuli portae interioris quinquaginta cubitos;", "brenton": "And the open space of the gate without to the open space of the porch of the gate within was fifty cubits."}}, {"v": 16, "ref": "40:16", "o": "וְ/חַלֹּנ֣וֹת אֲטֻמ֣וֹת אֶֽל הַ/תָּאִ֡ים וְ/אֶל֩ אֵלֵי/הֵ֨מָה לִ/פְנִ֤ימָה לַ/שַּׁ֨עַר֙ סָבִ֣יב סָבִ֔יב וְ/כֵ֖ן לָ/אֵֽלַמּ֑וֹת וְ/חַלּוֹנ֞וֹת סָבִ֤יב סָבִיב֙ לִ/פְנִ֔ימָה וְ/אֶל אַ֖יִל תִּמֹרִֽים", "en": {"kjv": "And there were narrow windows to the little chambers, and to their posts within the gate round about, and likewise to the arches: and windows were round about inward: and upon each post were palm trees.", "web": "There were closed windows to the lodges, and to their posts within the gate all around, and likewise to the arches; and windows were around inward; and on each post were palm trees.", "bsb": "The gate chambers and their side pillars had beveled windows all around the inside of the gateway. The porticos also had windows all around on the inside. Each side pillar was decorated with palm trees.", "asv": "And there were closed windows to the lodges, and to their posts within the gate round about, and likewise to the arches; and windows were round about inward; and upon each post were palm-trees.", "ylt": "and narrow windows are unto the little chambers, and unto their posts at the inside of the gate all round about--and so to the arches--and windows all round about are at the inside, and at the post are palm-trees.", "dra": "And slanting windows in the little chambers, and in their fronts, which were within the gate on every side round about: and in like manner there were also in the porches windows round about within, and before the fronts the representation of palm trees.", "bbe": "And the rooms and their uprights had sloping windows inside the doorway all round, and in the same way the covered way had windows all round on the inside: and on every upright there were palm-trees.", "geneva": "And there were narrowe windowes in the chambers, and in their postes within the gate round about, and likewise to the arches: and the windowes went rounde about within: and vpon the postes were palme trees.", "wycliffe": "And he mat wyndows naraw with out and large with ynne, in the chaumbris and frountis of tho, that weren with ynne the yate on ech side bi cumpas. Sotheli in lijk maner also wyndows weren in the porchis bi cumpas with ynne; and the peynture of palm trees was grauun bifor the frountis.", "rotherham": "And latticed windows had the lodges, even towards their projections within the gate round about on every side, and, so, had the recesses, —and windows round about on every side inwards, and against each projection, palm trees.", "darby": "And there were closed windows to the chambers, and to their posts within the gate round about, and likewise to the projections; and the windows round about were inward; and upon [each] post were palm-trees.", "twenty": "", "jps": "And there were narrow windows to the cells and to their posts within the gate round about, and likewise to the arches; and windows were round about inward; and upon each post were palm-trees.", "acv": "And there were closed windows to the little chambers, and to their posts within the gate round about, and likewise to the arches. And windows were round about inward, and upon each post were palm trees.", "anderson": "", "haweis": "", "noyes": "And there were closed windows to the chambers and to their wall-pillars inward toward the gate round about, and likewise to the cornices; there were windows round about within, and upon the wall-pillars were palm-trees.", "webster": "And [there were] narrow windows to the little chambers, and to their posts within the gate around, and likewise to the arches: and windows [were] around inward: and upon [each] post [were] palm-trees.", "vulgate": "et fenestras obliquas in thalamis et in frontibus eorum quae erant intra portam undique per circuitum similiter autem erant et in vestibulis fenestrae per gyrum intrinsecus et ante frontes pictura palmarum;", "brenton": "And there were secret windows to the chambers, and to the porches within the gate of the court round about, and in the same manner windows to the porches round about within: and on the porch there were palm-trees on this side and on that side."}}, {"v": 17, "ref": "40:17", "o": "וַ/יְבִיאֵ֗/נִי אֶל הֶֽ/חָצֵר֙ הַ/חִ֣יצוֹנָ֔ה וְ/הִנֵּ֤ה לְשָׁכוֹת֙ וְ/רִֽצְפָ֔ה עָשׂ֥וּי לֶ/חָצֵ֖ר סָבִ֣יב סָבִ֑יב שְׁלֹשִׁ֥ים לְשָׁכ֖וֹת אֶל הָ/רִֽצְפָֽה", "en": {"kjv": "Then brought he me into the outward court, and, lo, there were chambers, and a pavement made for the court round about: thirty chambers were upon the pavement.", "web": "Then brought he me into the outer court; and behold, there were rooms and a pavement, made for the court all around: thirty rooms were on the pavement.", "bsb": "Then he brought me into the outer court, and there were chambers and a pavement laid out all around the court. Thirty chambers faced the pavement,", "asv": "Then brought he me into the outer court; and, lo, there were chambers and a pavement, made for the court round about: thirty chambers were upon the pavement.", "ylt": "And he bringeth me in unto the outer court, and lo, chambers and a pavement made for the court all round about--thirty chambers on the pavement--", "dra": "And he brought me into the outward court, and behold there were chambers, and a pavement of stone in the court round about: thirty chambers encompassed the pavement.", "bbe": "Then he took me into the outer square, and there were rooms and a stone floor made for the open square all round: there were thirty rooms on the stone floor.", "geneva": "Then brought he me into the outwarde court, and lo, there were chambers, and a pauement made for the court round about, and thirtie chambers were vpon the pauement.", "wycliffe": "And he ledde me out to the outermere halle, and lo! tresories, and pawment arayed with stoon in the halle bi cumpas; thretti tresories in the cumpas of the pawment;", "rotherham": "Then he brought me into the outer court, and lo! chambers and a tesselated pavement, made to the court round about on every side,—thirty chambers against the pavement,", "darby": "And he brought me into the outer court, and behold, there were cells, and a pavement made for the court round about: thirty cells were upon the pavement.", "twenty": "", "jps": "Then brought he me into the outer court, and, lo, there were chambers and a pavement, made for the court round about; thirty chambers were upon the pavement.", "acv": "Then he brought me into the outer court. And, lo, there were chambers and a pavement, made for the court round about; thirty chambers were upon the pavement.", "anderson": "", "haweis": "", "noyes": "Then he brought me into the outer court, and behold, there were rooms, and a pavement made for the court round about; thirty rooms were upon the pavement.", "webster": "Then he brought me into the outward court, and lo, [there were] chambers, and a pavement made for the court around: thirty chambers [were] upon the pavement.", "vulgate": "et eduxit me ad atrium exterius et ecce gazofilacia et pavimentum stratum lapide in atrio per circuitum triginta gazofilacia in circuitu pavimenti;", "brenton": "And he brought me into the inner court, and, behold, there were chambers, and peristyles round about the court; thirty chambers within the ranges of columns."}}, {"v": 18, "ref": "40:18", "o": "וְ/הָ/רִֽצְפָה֙ אֶל כֶּ֣תֶף הַ/שְּׁעָרִ֔ים לְ/עֻמַּ֖ת אֹ֣רֶךְ הַ/שְּׁעָרִ֑ים הָ/רִֽצְפָ֖ה הַ/תַּחְתּוֹנָֽה", "en": {"kjv": "And the pavement by the side of the gates over against the length of the gates was the lower pavement.", "web": "The pavement was by the side of the gates, answerable to the length of the gates, even the lower pavement.", "bsb": "which flanked the gateways and corresponded to the length of the gates; this was the lower pavement.", "asv": "And the pavement was by the side of the gates, answerable unto the length of the gates, even the lower pavement.", "ylt": "and the pavement unto the side of the gates over-against the length of the gates is the lower pavement;", "dra": "And the pavement in the front of the gates according to the length of the gates was lower.", "bbe": "And the stone floor was by the side of the doorways, and was as wide as the doorways were long, even the lower floor.", "geneva": "And the pauement was by the side of the gates ouer against the length of the gates, and the pauement was beneath.", "wycliffe": "and the pawment was bynethe in the front of the yatis, bi the lengthe of the yatis.", "rotherham": "And the pavement, was against the side of the gates, answering to the length of the gates,—the lower pavement,", "darby": "And the pavement was by the side of the gates, answering to the length of the gates, [namely] the lower pavement.", "twenty": "", "jps": "And the pavement was by the side of the gates, corresponding unto the length of the gates, even the lower pavement.", "acv": "And the pavement was by the side of the gates, answerable to the length of the gates, even the lower pavement.", "anderson": "", "haweis": "", "noyes": "And the pavement at the sides of the gates, by the length of the gates, was the lower pavement.", "webster": "And the pavement by the side of the gates over against the length of the gates [was] the lower pavement.", "vulgate": "et pavimentum in fronte portarum secundum longitudinem portarum erat inferius;", "brenton": "And the porticos were behind the gates; according to the length of the gates, was the lower peristyle."}}, {"v": 19, "ref": "40:19", "o": "וַ/יָּ֣מָד רֹ֡חַב מִ/לִּ/פְנֵי֩ הַ/שַּׁ֨עַר הַ/תַּחְתּ֜וֹנָ/ה לִ/פְנֵ֨י הֶ/חָצֵ֧ר הַ/פְּנִימִ֛י מִ/ח֖וּץ מֵאָ֣ה אַמָּ֑ה הַ/קָּדִ֖ים וְ/הַ/צָּפֽוֹן", "en": {"kjv": "Then he measured the breadth from the forefront of the lower gate unto the forefront of the inner court without, an hundred cubits eastward and northward.", "web": "Then he measured the breadth from the forefront of the lower gate to the forefront of the inner court outside, one hundred cubits, both on the east and on the north.", "bsb": "Then he measured the distance from the front of the lower gateway to the outside of the inner court; it was a hundred cubits on the east side as well as on the north.", "asv": "Then he measured the breadth from the forefront of the lower gate unto the forefront of the inner court without, a hundred cubits, both on the east and on the north.", "ylt": "and he measureth the breadth from before the lower gate, to the front of the inner court, on the outside, a hundred cubits, eastward and northward.", "dra": "And he measured the breadth from the face of the lower gate to the front of the inner court without, a hundred cubits to the east, and to the north.", "bbe": "Then he took the measure of the square across, from before the lower doorway inside to before the inner doorway outside, one hundred cubits. And he took me in the direction of the north,", "geneva": "Then hee measured the breadth from the forefront of the lower gate without, vnto the forefront of the court within, an hundreth cubits Eastward and Northward.", "wycliffe": "And he mat the breede fro the face of the lowere yate til to the frount of the ynnere halle with outforth, an hundrid cubitis at the eest, and at the north.", "rotherham": "Then measured he the breadth, from the front of the lower gate, to the front of the inner court on the outside one hundred cubits,—to the east and the north.", "darby": "And he measured the breadth from the front of the lower gate unto the front of the inner court outside, a hundred cubits eastward and northward.", "twenty": "", "jps": "Then he measured the breadth from the forefront of the lower gate unto the forefront of the inner court without, a hundred cubits, eastward as also northward.", "acv": "Then he measured the breadth from the forefront of the lower gate to the forefront of the inner court outside, a hundred cubits, both on the east and on the north.", "anderson": "", "haweis": "", "noyes": "Then he measured the breadth from the front of the lower gate to the front of the inner court without, a hundred cubits toward the east and toward the north.", "webster": "Then he measured the breadth from the front of the lower gate to the front of the inner court without, a hundred cubits eastward and northward.", "vulgate": "et mensus est latitudinem a facie portae inferioris usque ad frontem atrii interioris extrinsecus centum cubitos ad orientem et ad aquilonem;", "brenton": "And he measured the breadth of the court, from the open space of the outer gate inwards to the open space of the gate looking outwards: a hundred cubits was the distance to the place of the gate looking eastward: and he brought me to the north;"}}, {"v": 20, "ref": "40:20", "o": "וְ/הַ/שַּׁ֗עַר אֲשֶׁ֤ר פָּנָי/ו֙ דֶּ֣רֶךְ הַ/צָּפ֔וֹן לֶ/חָצֵ֖ר הַ/חִֽיצוֹנָ֑ה מָדַ֥ד אָרְכּ֖/וֹ וְ/רָחְבּֽ/וֹ", "en": {"kjv": "And the gate of the outward court that looked toward the north, he measured the length thereof, and the breadth thereof.", "web": "The gate of the outer court whose prospect is toward the north, he measured its length and its breadth.", "bsb": "He also measured the length and width of the gateway of the outer court facing north.", "asv": "And the gate of the outer court whose prospect is toward the north, he measured the length thereof and the breadth thereof.", "ylt": "As to the gate of the outer court whose front is northward, he hath measured its length and its breadth;", "dra": "He measured also both the length and the breadth of the gate of the outward court, which looked northward.", "bbe": "And there was a doorway to the outer square, looking to the north; and he took the measure of it to see how wide and how long it was.", "geneva": "And the gate of the outwarde court, that looked toward the North, measured he after the length and breadth thereof.", "wycliffe": "And he mat bothe in lengthe and in breede the yate that bihelde the weie of the north, of the outermore halle.", "rotherham": "And as for the gate which looked towards the north, pertaining to the outer court, he measured the length thereof, and the breadth thereof.", "darby": "And the gate of the outer court, that looked toward the north, he measured its length and its breadth.", "twenty": "", "jps": "And the gate of the outer court that looked toward the north, he measured the length thereof and the breadth thereof.", "acv": "And the gate of the outer court whose view is toward the north, he measured the length of it and the breadth of it.", "anderson": "", "haweis": "", "noyes": "And as for the gate that looked toward the north in the outer court, he measured the length thereof, and the breadth thereof.", "webster": "And the gate of the outward court that looked towards the north, he measured its length, and its breadth.", "vulgate": "portam quoque quae respiciebat viam aquilonis atrii exterioris mensus est tam in longitudine quam in latitudine;", "brenton": "and behold a gate looking northwards belonging to the outer court, and he measured it, both the length of it and the breadth;"}}, {"v": 21, "ref": "40:21", "o": "ו/תא/ו וְ/תָאָ֗י/ו שְׁלוֹשָׁ֤ה מִ/פּוֹ֙ וּ/שְׁלֹשָׁ֣ה מִ/פּ֔וֹ ו/איל/ו וְ/אֵילָ֤י/ו ו/אלמ/ו וְ/אֵֽלַמָּי/ו֙ הָיָ֔ה כְּ/מִדַּ֖ת הַ/שַּׁ֣עַר הָ/רִאשׁ֑וֹן חֲמִשִּׁ֤ים אַמָּה֙ אָרְכּ֔/וֹ וְ/רֹ֕חַב חָמֵ֥שׁ וְ/עֶשְׂרִ֖ים בָּ/אַמָּֽה", "en": {"kjv": "And the little chambers thereof were three on this side and three on that side; and the posts thereof and the arches thereof were after the measure of the first gate: the length thereof was fifty cubits, and the breadth five and twenty cubits.", "web": "The lodges of it were three on this side and three on that side; and its posts and its arches were after the measure of the first gate: its length was fifty cubits, and the breadth twenty-five cubits.", "bsb": "Its three gate chambers on each side, its side pillars, and its portico all had the same measurements as the first gate: fifty cubits long and twenty-five cubits wide.", "asv": "And the lodges thereof were three on this side and three on that side; and the posts thereof and the arches thereof were after the measure of the first gate: the length thereof was fifty cubits, and the breadth five and twenty cubits.", "ylt": "and its little chambers, three on this side, and three on that side, and its posts and its arches have been according to the measure of the first gate, fifty cubits its length, and the breadth five and twenty by the cubit;", "dra": "And the little chambers thereof three on this side, and three on that side: and the front thereof, and the porch thereof according to the measure of the former gate, fifty cubits long, and five and twenty cubits broad.", "bbe": "And it had three rooms on this side of it and three on that; its uprights and its covered ways were the same size as those of the first doorway: it was fifty cubits long and twenty-five cubits wide.", "geneva": "And the chambers thereof were, three on this side, and three on that side, and the postes thereof and the arches thereof were after the measure of the first gate: the length thereof was fiftie cubites, and the breadth fiue and twentie cubites.", "wycliffe": "And he mat the chaumbris therof, thre on this side, and thre on that side, and the frount therof, and the porche therof, bi the mesure of the formere yate; the lengthe therof of fifti cubitis, and the breede therof of fyue and twenti cubitis.", "rotherham": "And the lodges thereof were three on this side and three on that side, and the projections thereof and the recesses thereof were according to the measure of the first gate, fifty cubits the length thereof, and, the breadth, twenty-five, by the cubit.", "darby": "And its chambers were three on this side and three on that side; and its posts and its projections were according to the measure of the first gate: its length was fifty cubits, and breadth five and twenty cubits.", "twenty": "", "jps": "And the cells thereof were three on this side and three on that side; and the posts thereof and the arches thereof were after the measure of the first gate; the length thereof was fifty cubits, and the breadth five and twenty cubits.", "acv": "And the little chambers of it were three on this side and three on that side. And the posts of it and the arches of it were according to the measure of the first gate: the length of it was fifty cubits, and the breadth twenty-five cubits.", "anderson": "", "haweis": "", "noyes": "And the chambers thereof were three on this side, and three on that side. And the border thereof, and the cornices thereof, were of the same measure as the former gate; the length thereof was fifty cubits, and the breadth five and twenty cubits.", "webster": "And the little chambers of it [were] three on this side and three on that side; and its posts and its arches were after the measure of the first gate; its length [was] fifty cubits, and its breadth five and twenty cubits.", "vulgate": "et thalamos eius tres hinc et tres inde et frontem eius et vestibulum eius secundum mensuram portae prioris quinquaginta cubitorum longitudinem eius et latitudinem viginti quinque cubitorum;", "brenton": "and the chambers, three on this side and three on that; and the posts, and the porches, and the palm-trees thereof: and they were according to the measures of the gate that looks eastward: the length thereof was fifty cubits, and the breadth thereof was twenty-five cubits."}}, {"v": 22, "ref": "40:22", "o": "ו/חלונ/ו וְ/חַלּוֹנָ֤י/ו ו/אלמ/ו וְ/אֵֽלַמָּי/ו֙ ו/תמר/ו וְ/תִ֣מֹרָ֔י/ו כְּ/מִדַּ֣ת הַ/שַּׁ֔עַר אֲשֶׁ֥ר פָּנָ֖י/ו דֶּ֣רֶךְ הַ/קָּדִ֑ים וּ/בְ/מַעֲל֥וֹת שֶׁ֨בַע֙ יַֽעֲלוּ ב֔/וֹ ו/אילמ/ו וְ/אֵֽילַמָּ֖י/ו לִ/פְנֵי/הֶֽם", "en": {"kjv": "And their windows, and their arches, and their palm trees, were after the measure of the gate that looketh toward the east; and they went up unto it by seven steps; and the arches thereof were before them.", "web": "The windows of it, and its arches, and the palm trees of it, were after the measure of the gate whose prospect is toward the east; and they went up to it by seven steps; and its arches were before them.", "bsb": "Its windows, portico, and palm trees had the same measurements as those of the gate facing east. Seven steps led up to it, with its portico opposite them.", "asv": "And the windows thereof, and the arches thereof, and the palm-trees thereof, were after the measure of the gate whose prospect is toward the east; and they went up unto it by seven steps; and the arches thereof were before them.", "ylt": "and its windows, and its arches, and its palm-trees are according to the measure of the gate whose face is eastward, and by seven steps they go up on it, and its arches are before them.", "dra": "And the windows thereof, and the porch, and the gravings according to the measure of the gate that looked to the east, and they went up to it by seven steps, and a porch was before it.", "bbe": "And its windows, and the windows of its covered ways, and its palm-trees, were the same as those of the doorway looking to the east; and there were seven steps up to it; and the covered way went inside.", "geneva": "And their windowes, and their arches with their palme trees, were after the measure of the gate that looketh toward the East, and the going vp vnto it had seuen steppes, and the arches therof were before them.", "wycliffe": "Sotheli the wyndows therof, and the porche, and the grauyngis, weren bi the mesure of the yate that bihelde to the eest; and the stiyng therof was of seuene degrees, and a porche was bifore it.", "rotherham": "And the windows thereof and the recesses thereof and the palm-trees thereof were according to the measure of the gate that looked toward the east,—and by seven steps, they ascend it, and their recesses were within,", "darby": "And its windows, and its projections, and its palm-trees were according to the measure of the gate that looked toward the east; and they went up to it by seven steps; and the projections thereof were before them.", "twenty": "", "jps": "And the windows thereof, and the arches thereof, and the palm-trees thereof, were after the measure of the gate that looketh toward the east; and it was ascended by seven steps; and the arches thereof were before them.", "acv": "And the windows of it, and the arches of it, and the palm trees of it, were according to the measure of the gate whose view is toward the east. And they went up to it by seven steps, and the arches of it were before them.", "anderson": "", "haweis": "", "noyes": "And the windows thereof, and the cornices thereof, and the palm-trees thereof were of the same measure as the gate which looked toward the east, and they went up to it by seven steps, and the cornices thereof were before them.", "webster": "And their windows, and their arches, and their palm-trees, [were] after the measure of the gate that looketh towards the east; and they went up to it by seven steps; and its arches [were] before them.", "vulgate": "fenestrae autem eius et vestibulum et scalpturae secundum mensuram portae quae respiciebat ad orientem et septem graduum erat ascensus eius et vestibulum ante eam;", "brenton": "And its windows, and its porches, and its palm-trees, were according to the dimensions of the gate looking eastward; and they went up to it by seven steps; and the porches were within."}}, {"v": 23, "ref": "40:23", "o": "וְ/שַׁ֨עַר֙ לֶ/חָצֵ֣ר הַ/פְּנִימִ֔י נֶ֣גֶד הַ/שַּׁ֔עַר לַ/צָּפ֖וֹן וְ/לַ/קָּדִ֑ים וַ/יָּ֧מָד מִ/שַּׁ֛עַר אֶל שַׁ֖עַר מֵאָ֥ה אַמָּֽה", "en": {"kjv": "And the gate of the inner court was over against the gate toward the north, and toward the east; and he measured from gate to gate an hundred cubits.", "web": "There was a gate to the inner court facing the other gate, on the north and on the east; and he measured from gate to gate one hundred cubits.", "bsb": "There was a gate to the inner court facing the north gate, just as there was on the east. He measured the distance from gateway to gateway to be a hundred cubits.", "asv": "And there was a gate to the inner court over against the other gate, both on the north and on the east; and he measured from gate to gate a hundred cubits.", "ylt": "And the gate of the inner court is over-against the gate at the north and at the east; and he measureth from gate unto gate, a hundred cubits.", "dra": "And the gate of the inner court was over against the gate of the north, and that of the east: and he measured from gate to gate a hundred cubits.", "bbe": "And there was a doorway to the inner square opposite the doorway on the north, like the doorway on the east; and he took the measure from doorway to doorway, a hundred cubits.", "geneva": "And the gate of the inner court stoode ouer against the gate towarde the North, and towarde the East, and hee measured from gate to gate an hundreth cubites.", "wycliffe": "And the yate of the ynnere halle was ayens the yate of the north, and ayens the eest yate; and he mat fro the yate til to the yate an hundrid cubitis.", "rotherham": "And the gate to the inner court, was over against the gate, to the north and to the east,—so he measured from gate to gate. one hundred cubits.", "darby": "And the gate of the inner court was opposite to the gate toward the north, and toward the east; and he measured from gate to gate a hundred cubits.", "twenty": "", "jps": "And there was a gate to the inner court over against the other gate, northward as also eastward; and he measured from gate to gate a hundred cubits.", "acv": "And there was a gate to the inner court opposite the other gate, both on the north and on the east, and he measured from gate to gate a hundred cubits.", "anderson": "", "haweis": "", "noyes": "And the gate of the inner court was over against the gate toward the north and east. And he measured from gate to gate a hundred cubits.", "webster": "And the gate of the inner court [was] over against the gate towards the north, and towards the east; and he measured from gate to gate a hundred cubits.", "vulgate": "et porta atrii interioris contra portam aquilonis et orientalem et mensus est a porta usque ad portam centum cubitos;", "brenton": "And there was a gate to the inner court looking toward the north gate, after the manner of the gate looking toward the east; and he measured the court from gate to gate, a hundred cubits."}}, {"v": 24, "ref": "40:24", "o": "וַ/יּוֹלִכֵ֨/נִי֙ דֶּ֣רֶךְ הַ/דָּר֔וֹם וְ/הִנֵּה שַׁ֖עַר דֶּ֣רֶךְ הַ/דָּר֑וֹם וּ/מָדַ֤ד איל/ו אֵילָי/ו֙ ו/אילמ/ו וְ/אֵ֣ילַמָּ֔י/ו כַּ/מִּדּ֖וֹת הָ/אֵֽלֶּה", "en": {"kjv": "After that he brought me toward the south, and behold a gate toward the south: and he measured the posts thereof and the arches thereof according to these measures.", "web": "He led me toward the south; and behold, a gate toward the south: and he measured its posts and its arches according to these measures.", "bsb": "Then he led me to the south side, and I saw a gateway facing south. He measured its side pillars and portico, and they had the same measurements as the others.", "asv": "And he led me toward the south; and, behold, a gate toward the south: and he measured the posts thereof and the arches thereof according to these measures.", "ylt": "And he causeth me to go southward, and lo, a gate southward, and he hath measured its posts and its arches according to these measures;", "dra": "And he brought me out to the way of the south, and behold the gate that looked to the south: and he measured the front thereof, and the porch thereof according to the former measures.", "bbe": "And he took me to the south, and I saw a doorway looking to the south: and he took the measure of its rooms and its uprights and its covered ways by these measures.", "geneva": "After that, he brought mee towarde the South, and loe, there was a gate towarde the South, and hee measured the postes thereof, and the arches thereof according to these measures.", "wycliffe": "And he ledde me out to the weie of the south, and lo! the yate that bihelde to the south; and he mat the frount therof, and the porche therof, bi the formere mesuris;", "rotherham": "Then he took me toward the south, and lo! a gate, toward the south,—and he measured the projections thereof and the recesses thereof, according to these measures.", "darby": "And he brought me toward the south: and behold, there was a gate toward the south; and he measured its posts and its projections according to these measures.", "twenty": "", "jps": "And he led me toward the south, and behold a gate toward the south; and he measured the posts thereof, and the arches thereof according to these measures.", "acv": "And he led me toward the south. And, behold, a gate toward the south. And he measured the posts of it and the arches of it according to these measures.", "anderson": "", "haweis": "", "noyes": "Then he led me toward the south; and behold, there was a gate toward the south; and he measured the border thereof and the cornices thereof according to those measures.", "webster": "After that he brought me towards the south, and behold a gate towards the south: and he measured its posts and its arches according to these measures.", "vulgate": "et duxit me ad viam australem et ecce porta quae respiciebat ad austrum et mensus est frontem eius et vestibulum eius iuxta mensuras superiores;", "brenton": "And he brought me to the south side, and behold a gate looking southwards: and he measured it, and its chambers, and its posts, and its porches, according to these dimensions."}}, {"v": 25, "ref": "40:25", "o": "וְ/חַלּוֹנִ֨ים ל֤/וֹ ו/ל/אילמ/ו וּ/לְ/אֵֽילַמָּי/ו֙ סָבִ֣יב סָבִ֔יב כְּ/הַ/חֲלֹּנ֖וֹת הָ/אֵ֑לֶּה חֲמִשִּׁ֤ים אַמָּה֙ אֹ֔רֶךְ וְ/רֹ֕חַב חָמֵ֥שׁ וְ/עֶשְׂרִ֖ים אַמָּֽה", "en": {"kjv": "And there were windows in it and in the arches thereof round about, like those windows: the length was fifty cubits, and the breadth five and twenty cubits.", "web": "There were windows in it and in its arches all around, like those windows: the length was fifty cubits, and the breadth twenty-five cubits.", "bsb": "Both the gateway and its portico had windows all around, like the other windows. It was fifty cubits long and twenty-five cubits wide.", "asv": "And there were windows in it and in the arches thereof round about, like those windows: the length was fifty cubits, and the breadth five and twenty cubits.", "ylt": "and windows are to it and to its arches all round about, like these windows, fifty cubits the length, and the breadth five and twenty cubits;", "dra": "And the windows thereof, and the porches round about, as the other windows: the length was fifty cubits, and the breadth five and twenty cubits.", "bbe": "And there were windows in it and in the covered way all round, like the other windows: it was fifty cubits long and twenty-five cubits wide.", "geneva": "And there were windowes in it, and in the arches thereof round about, like those windowes: the height was fiftie cubites, and the breadth fiue and twentie cubites.", "wycliffe": "and the wyndows therof, and the porchis in cumpas, as othere wyndows; the lengthe of fifti cubitis, and the breede of fyue and twenti cubitis.", "rotherham": "And windows were there to it, and the recesses thereof round about on all sides, like these windows,—fifty cubits in length, and in breadth, five-and-twenty cubits.", "darby": "And there were windows to it and to its projections round about, like those windows: the length was fifty cubits, and the breadth five and twenty cubits.", "twenty": "", "jps": "And there were windows in it and in the arches thereof round about, like those windows; the length was fifty cubits, and the breadth five and twenty cubits.", "acv": "And there were windows in it, and in the arches of it round about, like those windows: the length was fifty cubits, and the breadth twenty-five cubits.", "anderson": "", "haweis": "", "noyes": "And there were windows in it, and within the cornices thereof round about, like those windows; the length was fifty cubits, and the breadth five and twenty cubits.", "webster": "And [there were] windows in it and in its arches around, like those windows: the length [was] fifty cubits, and the breadth five and twenty cubits.", "vulgate": "et fenestras eius et vestibula in circuitu sicut fenestras ceteras quinquaginta cubitorum longitudine et latitudine viginti quinque cubitorum;", "brenton": "And its windows and its porches round about were according to the windows of the porch: the length thereof was fifty cubits, and the breadth thereof was five and twenty cubits."}}, {"v": 26, "ref": "40:26", "o": "וּ/מַעֲל֤וֹת שִׁבְעָה֙ עלות/ו עֹֽלוֹתָ֔י/ו ו/אלמ/ו וְ/אֵֽלַמָּ֖י/ו לִ/פְנֵי/הֶ֑ם וְ/תִמֹרִ֣ים ל֗/וֹ אֶחָ֥ד מִ/פּ֛וֹ וְ/אֶחָ֥ד מִ/פּ֖וֹ אֶל איל/ו אֵילָֽי/ו", "en": {"kjv": "And there were seven steps to go up to it, and the arches thereof were before them: and it had palm trees, one on this side, and another on that side, upon the posts thereof.", "web": "There were seven steps to go up to it, and its arches were before them; and it had palm trees, one on this side, and another on that side, on its posts.", "bsb": "Seven steps led up to it, and its portico was opposite them; it had palm trees on its side pillars, one on each side.", "asv": "And there were seven steps to go up to it, and the arches thereof were before them; and it had palm-trees, one on this side, and another on that side, upon the posts thereof.", "ylt": "and seven steps are its ascent, and its arches are before them, and palm-trees are to it, one on this side, and one on that side, at its posts;", "dra": "And there were seven steps to go up to it: and a porch before the doors thereof: and there were graven palm trees, one on this side, and another on that side in the front thereof.", "bbe": "And there were seven steps up to it, and its covered way went inside: and it had palm-trees, one on this side and one on that, on its uprights.", "geneva": "And there were seuen steps to go vp to it, and the arches thereof were before them: and it had palme trees, one on this side, and another on that side vpon the post thereof.", "wycliffe": "And bi seuene degrees me stiede to it, and `an halle was bifor the yatis therof; and palme trees weren grauun, oon in this side, and another in that side in the frount therof.", "rotherham": "And seven steps the ascents thereof, with its recesses within,—and it had palm trees one on this side and one on that side against the projections thereof.", "darby": "And there were seven steps to go up to it; and its projections were before them; and it had palm-trees, one on this side and one on that side, upon its posts.", "twenty": "", "jps": "And there were seven steps to go up to it, and the arches thereof were before them; and it had palm-trees, one on this side, and another on that side, upon the posts thereof.", "acv": "And there were seven steps to go up to it, and the arches of it were before them. And it had palm trees, one on this side, and another on that side, upon the posts of it.", "anderson": "", "haweis": "", "noyes": "And there were seven steps to go up to it, and the cornices thereof were before them; and it had palm-trees, one on this side and another on that side, upon the wall-pillars thereof.", "webster": "And [there were] seven steps to go up to it, and its arches [were] before them: and it had palm-trees, one on this side, and another on that side, upon its posts.", "vulgate": "et in gradibus septem ascendebatur ad eam et vestibulum ante fores eius et celatae palmae erant una hinc et altera inde in fronte eius;", "brenton": "And it had seven steps, and porches within: and it had palm-trees on the posts, one on one side, and one on the other side."}}, {"v": 27, "ref": "40:27", "o": "וְ/שַׁ֛עַר לֶ/חָצֵ֥ר הַ/פְּנִימִ֖י דֶּ֣רֶךְ הַ/דָּר֑וֹם וַ/יָּ֨מָד מִ/שַּׁ֧עַר אֶל הַ/שַּׁ֛עַר דֶּ֥רֶךְ הַ/דָּר֖וֹם מֵאָ֥ה אַמּֽוֹת", "en": {"kjv": "And there was a gate in the inner court toward the south: and he measured from gate to gate toward the south an hundred cubits.", "web": "There was a gate to the inner court toward the south: and he measured from gate to gate toward the south a hundred cubits.", "bsb": "The inner court also had a gate facing south, and he measured the distance from gateway to gateway toward the south to be a hundred cubits.", "asv": "And there was a gate to the inner court toward the south: and he measured from gate to gate toward the south a hundred cubits.", "ylt": "and the gate of the inner court is southward, and he measureth from gate unto gate southward, a hundred cubits.", "dra": "And there was a gate of the inner court towards the south: and he measured from gate to gate towards the south, a hundred cubits.", "bbe": "And there was a doorway to the inner square looking to the south: he took the measure from doorway to doorway to the south, a hundred cubits.", "geneva": "And there was a gate in the inner court towarde the South, and he measured from gate to gate towarde the South an hundreth cubites.", "wycliffe": "And the yate of the ynnere halle was in the weie of the south; and he mat fro the yate til to the yate in the weie of the south, an hundrid cubitis.", "rotherham": "And a gate, had the inner court towards the south,—so he measured from gate to gate toward the south, a hundred cubits.", "darby": "And there was a gate to the inner court toward the south; and he measured from gate to gate toward the south, a hundred cubits.", "twenty": "", "jps": "And there was a gate to the inner court toward the south; and he measured from gate to gate toward the south a hundred cubits.", "acv": "And there was a gate to the inner court toward the south. And he measured from gate to gate toward the south a hundred cubits.", "anderson": "", "haweis": "", "noyes": "And there was a gate in the inner court toward the south; and he measured from gate to gate toward the south a hundred cubits.", "webster": "And [there was] a gate in the inner court towards the south: and he measured from gate to gate towards the south a hundred cubits.", "vulgate": "et porta atrii interioris in via australi et mensus est a porta usque ad portam in via australi centum cubitos;", "brenton": "And there was a gate opposite the gate of the inner court southward: and he measured the court from gate to gate, a hundred cubits in breadth southward."}}, {"v": 28, "ref": "40:28", "o": "וַ/יְבִיאֵ֛/נִי אֶל חָצֵ֥ר הַ/פְּנִימִ֖י בְּ/שַׁ֣עַר הַ/דָּר֑וֹם וַ/יָּ֨מָד֙ אֶת הַ/שַּׁ֣עַר הַ/דָּר֔וֹם כַּ/מִּדּ֖וֹת הָ/אֵֽלֶּה", "en": {"kjv": "And he brought me to the inner court by the south gate: and he measured the south gate according to these measures;", "web": "Then he brought me to the inner court by the south gate: and he measured the south gate according to these measures;", "bsb": "Next he brought me into the inner court through the south gate, and he measured the south gate; it had the same measurements as the others.", "asv": "Then he brought me to the inner court by the south gate: and he measured the south gate according to these measures;", "ylt": "And he bringeth me in unto the inner court by the south gate, and he measureth the south gate according to these measures;", "dra": "And he brought me into the inner court at the south gate: and he measured the gate according to the former measures.", "bbe": "Then he took me to the inner square by the south doorway: and he took the measure of the south doorway by these measures;", "geneva": "And he brought me into the inner court by the South gate, and he measured the South gate according to these measures,", "wycliffe": "And he ledde me in to the ynnere halle, to the south yate; and he mat the yate bi the formere mesuris;", "rotherham": "Yea when he brought me to the inner court through the south gate, then measured he the south gate, according to these measures;", "darby": "And he brought me into the inner court by the south gate; and he measured the south gate according to these measures:", "twenty": "", "jps": "Then he brought me to the inner court by the south gate; and he measured the south gate according to these measures;", "acv": "Then he brought me to the inner court by the south gate. And he measured the south gate according to these measures,", "anderson": "", "haweis": "", "noyes": "And he brought me to the inner court through the south gate; and he measured the south gate according to the same measures.", "webster": "And he brought me to the inner court by the south gate; and he measured the south gate according to these measures;", "vulgate": "et introduxit me in atrium interius ad portam australem et mensus est portam iuxta mensuras superiores;", "brenton": "And he brought me into the inner court of the south gate: and he measured the gate according to these measures;"}}, {"v": 29, "ref": "40:29", "o": "ו/תא/ו וְ/תָאָ֞י/ו ו/איל/ו וְ/אֵילָ֤י/ו ו/אלמ/ו וְ/אֵֽלַמָּי/ו֙ כַּ/מִּדּ֣וֹת הָ/אֵ֔לֶּה וְ/חַלּוֹנ֥וֹת ל֛/וֹ ו/ל/אלמ/ו וּ/לְ/אֵלַמָּ֖י/ו סָבִ֣יב סָבִ֑יב חֲמִשִּׁ֤ים אַמָּה֙ אֹ֔רֶךְ וְ/רֹ֕חַב עֶשְׂרִ֥ים וְ/חָמֵ֖שׁ אַמּֽוֹת", "en": {"kjv": "And the little chambers thereof, and the posts thereof, and the arches thereof, according to these measures: and there were windows in it and in the arches thereof round about: it was fifty cubits long, and five and twenty cubits broad.", "web": "and its lodges, and its posts, and its arches, according to these measures: and there were windows in it and in its arches all around; it was fifty cubits long, and twenty-five cubits broad.", "bsb": "Its gate chambers, side pillars, and portico had the same measurements as the others. Both the gateway and its portico had windows all around; it was fifty cubits long and twenty-five cubits wide.", "asv": "and the lodges thereof, and the posts thereof, and the arches thereof, according to these measures: and there were windows in it and in the arches thereof round about; it was fifty cubits long, and five and twenty cubits broad.", "ylt": "and its little chambers, and its posts, and its arches are according to these measures, and windows are to it and to its arches all round about; fifty cubits the length, and the breadth twenty and five cubits.", "dra": "The little chamber thereof, and the front thereof, and the porch thereof with the same measures: and the windows thereof, and the porch thereof round about it was fifty cubits in length, and five and twenty cubits in breadth.", "bbe": "And the rooms in it and the uprights and the covered ways, by these measures:", "geneva": "And the chambers thereof, and the postes thereof, and the arches thereof according to these measures, and there were windowes in it, and in the arches thereof rounde about, it was fiftie cubites long and fiue and twentie cubites broade.", "wycliffe": "the chaumbre therof, and the frount therof, and the porche therof bi the same mesuris; and he mat the wyndows therof, and the porche therof in cumpas; fifti cubitis of lengthe, and fyue and twenti cubitis of breede.", "rotherham": "and the lodges thereof and the projections thereof and the recesses, thereof, were according to these measures, and windows, were there to it, and to the recesses thereof round about on every side,—fifty cubits in length, and in breadth, twenty and five cubits;", "darby": "and its chambers, and its posts, and its projections, according to these measures; and there were windows to it and to its projections round about: the length was fifty cubits, and the breadth twenty-five cubits.", "twenty": "", "jps": "and the cells thereof, and the posts thereof, and the arches thereof, according to these measures; and there were windows in it and in the arches thereof round about; it was fifty cubits long, and five and twenty cubits broad.", "acv": "and the little chambers of it, and the posts of it, and the arches of it, according to these measures. And there were windows in it and in the arches of it round about. It was fifty cubits long, and twenty-five cubits broad.", "anderson": "", "haweis": "", "noyes": "And the chambers thereof, and the border thereof, and the cornices thereof were according to those measures. And there were windows in it, and within the cornices thereof, round about; it was fifty cubits long, and five and twenty cubits broad.", "webster": "And its little chambers, and its posts, and its arches, according to these measures; and [there were] windows in it and in its arches around: [it was] fifty cubits long, and five and twenty cubits broad.", "vulgate": "thalamum eius et frontem eius et vestibulum eius hisdem mensuris et fenestras eius et vestibulorum eius in circuitu quinquaginta cubitos longitudinis et latitudinis viginti quinque cubitos;", "brenton": "and the chambers, and the posts,"}}, {"v": 30, "ref": "40:30", "o": "וְ/אֵֽלַמּ֖וֹת סָבִ֣יב סָבִ֑יב אֹ֗רֶךְ חָמֵ֤שׁ וְ/עֶשְׂרִים֙ אַמָּ֔ה וְ/רֹ֖חַב חָמֵ֥שׁ אַמּֽוֹת", "en": {"kjv": "And the arches round about were five and twenty cubits long, and five cubits broad.", "web": "There were arches all around, twenty-five cubits long, and five cubits broad.", "bsb": "(The porticoes around the inner court were twenty-five cubits long and five cubits deep.)", "asv": "And there were arches round about, five and twenty cubits long, and five cubits broad.", "ylt": "As to the arches all round about, the length is five and twenty cubits, and the breadth five cubits;", "dra": "And the porch round about was five and twenty cubits long, and five cubits broad.", "bbe": "And there were windows in it and in the covered way all round: it was fifty cubits long and twenty-five cubits wide.", "geneva": "And the arches round about were fiue and twenty cubites long, and fiue cubites broad.", "wycliffe": "And he mat the halle bi cumpas, the lengthe of fyue and twenti cubitis, and the breede therof of fyue cubitis.", "rotherham": "and there were recesses round about on every side;—in length, five and twenty cubits, and in breadth, five cubits;", "darby": "And there were projections round about, twenty-five cubits long, and five cubits broad.", "twenty": "", "jps": "And there were arches round about, five and twenty cubits long, and five cubits broad.", "acv": "And there were arches round about, twenty-five cubits long, and five cubits broad.", "anderson": "", "haweis": "", "noyes": "And the cornices round about were five and twenty cubits long, and five cubits broad.", "webster": "And the arches around [were] five and twenty cubits long, and five cubits broad.", "vulgate": "et vestibulum per gyrum longitudine viginti quinque cubitorum et latitudine quinque cubitorum;", "brenton": "and the porches, according to these measures: and there were windows to it and to the porches round about: its length was fifty cubits, and its breadth twenty-five cubits,"}}, {"v": 31, "ref": "40:31", "o": "וְ/אֵלַמָּ֗/ו אֶל חָצֵר֙ הַ/חִ֣צוֹנָ֔ה וְ/תִמֹרִ֖ים אֶל איל/ו אֵילָ֑י/ו וּ/מַעֲל֥וֹת שְׁמוֹנֶ֖ה מעל/ו מַעֲלָֽי/ו", "en": {"kjv": "And the arches thereof were toward the utter court; and palm trees were upon the posts thereof: and the going up to it had eight steps.", "web": "The arches of it were toward the outer court; and palm trees were on its posts: and the ascent to it had eight steps.", "bsb": "Its portico faced the outer court, and its side pillars were decorated with palm trees. Eight steps led up to it.", "asv": "And the arches thereof were toward the outer court; and palm-trees were upon the posts thereof: and the ascent to it had eight steps.", "ylt": "and its arches are unto the outer court, and palm-trees are unto its posts, and eight steps are its ascent.", "dra": "And the porch thereof to the outward court, and the palm trees thereof in the front: and there were eight steps to go up to it.", "bbe": "The covered way was on the side nearest the outer square; and there were palm-trees on the uprights: and there were eight steps going up to it.", "geneva": "And the arches thereof were towarde the vtter court, and palme trees were vpon the postes thereof, and the going vp to it had eight steppes.", "wycliffe": "And the porche therof was to the outermere halle, and the palm trees therof in the frount; and eiyte degrees weren, bi whiche me stiede thorouy it.", "rotherham": "and the recesses thereof reached unto the outer court, with palm-trees, against the projections thereof, and eight steps were the ascents thereof.", "darby": "And its projections were toward the outer court; and there were palm-trees upon its posts: and its ascent was [by] eight steps.", "twenty": "", "jps": "And the arches thereof were toward the outer court; and palm-trees were upon the posts thereof; and the going up to it had eight steps.", "acv": "And the arches of it were toward the outer court, and palm trees were upon the posts of it. And the ascent to it had eight steps.", "anderson": "", "haweis": "", "noyes": "And the cornices thereof were toward the outer court; and palm-trees were upon the wall-pillars thereof; and in going up to it there were eight steps.", "webster": "And its arches [were] towards the outer court; and palm-trees [were] upon its posts: and the ascent to it [had] eight steps.", "vulgate": "et vestibulum eius ad atrium exterius et palmas eius in fronte et octo gradus erant quibus ascendebatur per eam;", "brenton": "from the porch to the outer court: and there were palm-trees to the post thereof, and eight steps."}}, {"v": 32, "ref": "40:32", "o": "וַ/יְבִיאֵ֛/נִי אֶל הֶ/חָצֵ֥ר הַ/פְּנִימִ֖י דֶּ֣רֶךְ הַ/קָּדִ֑ים וַ/יָּ֣מָד אֶת הַ/שַּׁ֔עַר כַּ/מִּדּ֖וֹת הָ/אֵֽלֶּה", "en": {"kjv": "And he brought me into the inner court toward the east: and he measured the gate according to these measures.", "web": "He brought me into the inner court toward the east: and he measured the gate according to these measures;", "bsb": "And he brought me to the inner court on the east side, and he measured the gateway; it had the same measurements as the others.", "asv": "And he brought me into the inner court toward the east: and he measured the gate according to these measures;", "ylt": "And he bringeth me in unto the inner court eastward, and he measureth the gate according to these measures;", "dra": "And he brought me into the inner court by the way of the east: and he measured the gate according to the former measures.", "bbe": "And he took me into the inner square facing the east: and he took the measure of the doorway by these measures;", "geneva": "Againe he brought me into ye inner court toward the East, and he measured the gate according to these measures.", "wycliffe": "And he ledde me in to the ynnere halle, bi the eest weie; and he mat the yate by the formere mesures;", "rotherham": "And when he brought me unto the inner court toward the east, then measured he the gate, according to these measures;", "darby": "And he brought me into the inner court toward the east; and he measured the gate according to these measures:", "twenty": "", "jps": "And he brought me into the inner court toward the east; and he measured the gate according to these measures;", "acv": "And he brought me into the inner court toward the east. And he measured the gate according to these measures,", "anderson": "", "haweis": "", "noyes": "And he brought me to the inner court toward the east; and he measured the gate according to those measures.", "webster": "And he brought me into the inner court towards the east: and he measured the gate according to these measures.", "vulgate": "et introduxit me in atrium interius per viam orientalem et mensus est portam secundum mensuras superiores;", "brenton": "And he brought me in at the gate that looks eastward: and he measured it according to these measures:"}}, {"v": 33, "ref": "40:33", "o": "ו/תא/ו וְ/תָאָ֞י/ו ו/אל/ו וְ/אֵלָ֤י/ו ו/אלמ/ו וְ/אֵֽלַמָּי/ו֙ כַּ/מִּדּ֣וֹת הָ/אֵ֔לֶּה וְ/חַלּוֹנ֥וֹת ל֛/וֹ ו/ל/אלמ/ו וּ/לְ/אֵלַמָּ֖י/ו סָבִ֣יב סָבִ֑יב אֹ֚רֶךְ חֲמִשִּׁ֣ים אַמָּ֔ה וְ/רֹ֕חַב חָמֵ֥שׁ וְ/עֶשְׂרִ֖ים אַמָּֽה", "en": {"kjv": "And the little chambers thereof, and the posts thereof, and the arches thereof, were according to these measures: and there were windows therein and in the arches thereof round about: it was fifty cubits long, and five and twenty cubits broad.", "web": "and its lodges, and its posts, and its arches, according to these measures: and there were windows therein and in its arches all around; it was fifty cubits long, and twenty-five cubits broad.", "bsb": "Its gate chambers, side pillars, and portico had the same measurements as the others. Both the gateway and its portico had windows all around. It was fifty cubits long and twenty-five cubits wide.", "asv": "and the lodges thereof, and the posts thereof, and the arches thereof, according to these measures: and there were windows therein and in the arches thereof round about; it was fifty cubits long, and five and twenty cubits broad.", "ylt": "and its little chambers, and its posts, and its arches are according to these measures: and windows are to it and to its arches all round about, the length fifty cubits, and the breadth five and twenty cubits;", "dra": "The little chamber thereof, and the front thereof, and the porch thereof as before: and the windows thereof, and the porches thereof round about it was fifty cubits long, and five and twenty cubits broad.", "bbe": "And of the rooms in it and its uprights and its covered ways, by these measures: and there were windows in it and in the covered way round about: it was fifty cubits long and twenty-five cubits wide.", "geneva": "And the chambers thereof, and the postes thereof, and the arches thereof were according to these measures, and there were windowes therein, and in the arches thereof round about, it was fiftie cubites long, and fiue and twentie cubites broade.", "wycliffe": "the chaumbre therof, and the frount therof, and the porchis therof, as aboue; and he mat the wyndows therof, and the porchis therof in cumpas; the lengthe of fifti cubitis, and the breede of fyue and twenti cubitis; and the porche therof,", "rotherham": "and the lodges thereof and the projections thereof and the recesses thereof, according to these measures, and windows were there to it and to the recesses thereof, round about on every side,—in length fifty cubits, and in breadth, five and twenty cubits;", "darby": "and its chambers, and its posts, and its projections, according to these measures; and there were windows to it and to its projections round about: the length was fifty cubits, and the breadth twenty-five cubits.", "twenty": "", "jps": "and the cells thereof, and the posts thereof, and the arches thereof, according to these measures; and there were windows therein and in the arches thereof round about; it was fifty cubits long, and five and twenty cubits broad.", "acv": "and the little chambers of it, and the posts of it, and the arches of it, according to these measures. And there were windows in it and in the arches of it round about. It was fifty cubits long, and twenty-five cubits broad.", "anderson": "", "haweis": "", "noyes": "And the chambers thereof, and the border thereof, and the cornices thereof, were according to those measures; and there were windows in it, and in the cornices thereof, round about; the length was fifty cubits, and the breadth five and twenty cubits.", "webster": "And its little chambers, and its posts, and its arches, [were] according to these measures; and [there were] windows in it and in its arches around: [it was] fifty cubits long, and five and twenty cubits broad.", "vulgate": "thalamum eius et frontem eius et vestibula eius sicut supra et fenestras eius et vestibuli eius in circuitu longitudine quinquaginta cubitorum et latitudine viginti quinque cubitorum;", "brenton": "and the chambers, and the posts, and the porches according to these measures: and there were windows to it, and porches round about: the length of it was fifty cubits, and the breadth of it twenty-five cubits."}}, {"v": 34, "ref": "40:34", "o": "ו/אלמ/ו וְ/אֵלַמָּ֗י/ו לֶֽ/חָצֵר֙ הַ/חִ֣יצוֹנָ֔ה וְ/תִמֹרִ֥ים אֶל אל/ו אֵלָ֖י/ו מִ/פּ֣וֹ וּ/מִ/פּ֑וֹ וּ/שְׁמֹנֶ֥ה מַעֲל֖וֹת מעל/ו מַעֲלָֽי/ו", "en": {"kjv": "And the arches thereof were toward the outward court; and palm trees were upon the posts thereof, on this side, and on that side: and the going up to it had eight steps.", "web": "The arches of it were toward the outer court; and palm trees were on its posts, on this side, and on that side: and the ascent to it had eight steps.", "bsb": "Its portico faced the outer court, and its side pillars were decorated with palm trees on each side. Eight steps led up to it.", "asv": "And the arches thereof were toward the outer court; and palm-trees were upon the posts thereof, on this side, and on that side: and the ascent to it had eight steps.", "ylt": "and its arches are toward the outer court, and palm-trees are toward its posts, on this side and on that side, and eight steps are its ascent.", "dra": "And the porch thereof, that is, of the outward court: and the graven palm trees in the front thereof on this side and on that side: and the going up thereof was by eight steps.", "bbe": "And the covered way was on the side nearest the outer square; there were palm-trees on the uprights, on this side and on that: and there were eight steps going up to it.", "geneva": "And the arches thereof were towarde the vtter court, and palme trees were vpon the postes thereof, on this side and on that side, and the going vp to it had eight steppes.", "wycliffe": "that is, of the outermore halle; and palme trees grauun in the frount therof, on this side and on that side; and in eiyte degrees was the stiyng therof.", "rotherham": "and the recesses thereof reached to the outer court, with palm-trees, against the projections thereof, on this side and on that side,—and eight steps, were the ascents thereof.", "darby": "And its projections were toward the outer court; and there were palm-trees upon its posts on this side and on that side: and its ascent was [by] eight steps.", "twenty": "", "jps": "And the arches thereof were toward the outer court; and palm-trees were upon the posts thereof, on this side, and on that side; and the going up to it had eight steps.", "acv": "And the arches of it were toward the outer court, and palm trees were upon the posts of it, on this side, and on that side. And the ascent to it had eight steps.", "anderson": "", "haweis": "", "noyes": "And the cornices thereof were toward the outer court; and palm-trees were upon the wall-pillars thereof, on this side and on that side; and in going up to it there were eight steps.", "webster": "And its arches [were] towards the outward court; and palm-trees were upon its posts, on this side, and on that side: and the ascent to it [had] eight steps.", "vulgate": "et vestibulum eius id est atrii exterioris et palmae celatae in fronte eius hinc et inde et in octo gradibus ascensus eius;", "brenton": "And there were porches opening into the inner court, and palm-trees on the posts on this side and on that side: and it had eight steps."}}, {"v": 35, "ref": "40:35", "o": "וַ/יְבִיאֵ֖/נִי אֶל שַׁ֣עַר הַ/צָּפ֑וֹן וּ/מָדַ֖ד כַּ/מִּדּ֥וֹת הָ/אֵֽלֶּה", "en": {"kjv": "And he brought me to the north gate, and measured it according to these measures;", "web": "He brought me to the north gate: and he measured it according to these measures;", "bsb": "Then he brought me to the north gate and measured it. It had the same measurements as the others,", "asv": "And he brought me to the north gate: and he measureditaccording to these measures;", "ylt": "And he bringeth me in unto the north gate, and hath measured according to these measures;", "dra": "And he brought me into the gate that looked to the north: and he measured according to the former measures.", "bbe": "And he took me to the north doorway: and he took the measure of it by these measures;", "geneva": "After he brought mee to the North gate, and measured it, according to these measures,", "wycliffe": "And he ledde me in to the yate that bihelde to the north; and he mat bi the formere mesuris;", "rotherham": "And when he brought me to the north gate, then measured he according to these measures:", "darby": "And he brought me to the north gate, and he measured [it] according to these measures:", "twenty": "", "jps": "And he brought me to the north gate; and he measured it according to these measures;", "acv": "And he brought me to the north gate. And he measured it according to these measures,", "anderson": "", "haweis": "", "noyes": "And he brought me to the north gate, and measured it according to those measures;", "webster": "And he brought me to the north gate, and measured [it] according to these measures;", "vulgate": "et introduxit me ad portam quae respiciebat ad aquilonem et mensus est secundum mensuras superiores;", "brenton": "And he brought me in at the northern gate, and measured it according to these measures;"}}, {"v": 36, "ref": "40:36", "o": "תא/ו תָּאָי/ו֙ אל/ו אֵלָ֣י/ו ו/אלמ/ו וְ/אֵֽלַמָּ֔י/ו וְ/חַלּוֹנ֥וֹת ל֖/וֹ סָבִ֣יב סָבִ֑יב אֹ֚רֶךְ חֲמִשִּׁ֣ים אַמָּ֔ה וְ/רֹ֕חַב חָמֵ֥שׁ וְ/עֶשְׂרִ֖ים אַמָּֽה", "en": {"kjv": "The little chambers thereof, the posts thereof, and the arches thereof, and the windows to it round about: the length was fifty cubits, and the breadth five and twenty cubits.", "web": "its lodges, its posts, and its arches: and there were windows therein all around; the length was fifty cubits, and the breadth twenty-five cubits.", "bsb": "as did its gate chambers, side pillars, and portico. It also had windows all around. It was fifty cubits long and twenty-five cubits wide.", "asv": "the lodges thereof, the posts thereof, and the arches thereof: and there were windows therein round about; the length was fifty cubits, and the breadth five and twenty cubits.", "ylt": "its little chambers, its posts, and its arches; and windows are to it all round about: the length fifty cubits, and the breadth five and twenty cubits;", "dra": "The little chamber thereof, and the front thereof, and the porch thereof, and the windows thereof round about it was fifty cubits long, and five and twenty cubits broad.", "bbe": "Its rooms, its uprights, and its covered way had the same measures, and its covered way had windows all round: it was fifty cubits long and twenty-five cubits wide.", "geneva": "The chambers thereof, the postes thereof, and the arches thereof, and there were windowes therein round about: the height was fiftie cubits, and the breadth fiue and twentie cubites.", "wycliffe": "the chaumbre therof, and the frount therof, and the porche therof, and the wyndows therof bi cumpas; the lengthe of fifti cubitis, and the breede of fyue and twenti cubitis.", "rotherham": "the lodges thereof the projections thereof and the recesses thereof, with, windows, to it round about on every side,—in length, fifty cubits, and, in breadth, five and twenty cubits;", "darby": "its chambers, its posts, and its projections; and there were windows to it round about: the length was fifty cubits, and the breadth twenty-five cubits.", "twenty": "", "jps": "the cells thereof, the posts thereof, and the arches thereof; and there were windows therein round about; the length was fifty cubits, and the breadth five and twenty cubits.", "acv": "the little chambers of it, the posts of it, and the arches of it. And there were windows in it round about. The length was fifty cubits, and the breadth twenty-five cubits.", "anderson": "", "haweis": "", "noyes": "the chambers thereof, and the border thereof, and the cornices thereof; and there were windows to it, round about; the length was fifty cubits, and the breadth five and twenty cubits.", "webster": "Its little chambers, its posts, and its arches, and the windows to it around: the length [was] fifty cubits, and the breadth five and twenty cubits.", "vulgate": "thalamum eius frontem eius vestibulum eius et fenestras eius per circuitum longitudine quinquaginta cubitorum et latitudine viginti quinque cubitorum;", "brenton": "and the chambers, and the posts, and the porches: and it had windows round about, and it had its porches: the length of it was fifty cubits, and the breadth twenty-five cubits."}}, {"v": 37, "ref": "40:37", "o": "ו/איל/ו וְ/אֵילָ֗י/ו לֶֽ/חָצֵר֙ הַ/חִ֣יצוֹנָ֔ה וְ/תִמֹרִ֥ים אֶל איל/ו אֵילָ֖י/ו מִ/פּ֣וֹ וּ/מִ/פּ֑וֹ וּ/שְׁמֹנֶ֥ה מַעֲל֖וֹת מעל/ו מַעֲלָֽי/ו", "en": {"kjv": "And the posts thereof were toward the utter court; and palm trees were upon the posts thereof, on this side, and on that side: and the going up to it had eight steps.", "web": "The posts of it were toward the outer court; and palm trees were on its posts, on this side, and on that side: and the ascent to it had eight steps.", "bsb": "Its portico faced the outer court, and its side pillars were decorated with palm trees on each side. Eight steps led up to it.", "asv": "And the posts thereof were toward the outer court; and palm-trees were upon the posts thereof, on this side, and on that side: and the ascent to it had eight steps.", "ylt": "and its posts are to the outer court, and palm-trees are unto its posts, on this side and on that side, and eight steps are its ascent.", "dra": "And the porch thereof looked to the outward court: and the graving of palm trees in the front thereof was on this side and on that side: and the going up to it was by eight steps.", "bbe": "Its uprights were on the side nearest to the outer square; there were palm-trees on the uprights, on this side and on that: and there were eight steps going up to it.", "geneva": "And the postes thereof were towarde the vtter court, and palme trees were vpon the postes thereof on this side, and on that side, and the going vp to it had eight steps.", "wycliffe": "The porche therof bihelde to the outermore halle; and the grauyng of palm trees was in the frount therof, on this side and on that side; and in eiyte degrees was the stiyng therof.", "rotherham": "and, the recesses thereof, [reached] unto the outer court, with, palm-trees, against the projections thereof on this side and on that side,—and, eight steps, were the ascents thereof.", "darby": "And its posts were toward the outer court; and there were palm-trees upon its posts, on this side and on that side: and its ascent was [by] eight steps.", "twenty": "", "jps": "And the posts thereof were toward the outer court; and palm-trees were upon the posts thereof, on this side, and on that side; and the going up to it had eight steps.", "acv": "And the posts of it were toward the outer court, and palm trees were upon the posts of it, on this side, and on that side. And the ascent to it had eight steps.", "anderson": "", "haweis": "", "noyes": "And the cornices thereof were toward the outer court; and palm-trees were upon the wall-pillars thereof, on this side and on that side; and in going up to it there were eight steps.", "webster": "And its posts [were] towards the outer court; and palm-trees [were] upon its posts, on this side, and on that side: and the ascent to it [had] eight steps.", "vulgate": "vestibulum eius in atrium exterius et celatura palmarum in fronte illius hinc et inde et in octo gradibus ascensus eius;", "brenton": "And its porches were toward the inner court; and there were palm-trees to the posts on this side and on that side: and it had eight steps."}}, {"v": 38, "ref": "40:38", "o": "וְ/לִשְׁכָּ֣ה וּ/פִתְחָ֔/הּ בְּ/אֵילִ֖ים הַ/שְּׁעָרִ֑ים שָׁ֖ם יָדִ֥יחוּ אֶת הָ/עֹלָֽה", "en": {"kjv": "And the chambers and the entries thereof were by the posts of the gates, where they washed the burnt offering.", "web": "A room with its door was by the posts at the gates; there they washed the burnt offering.", "bsb": "There was a chamber with a doorway by the portico in each of the inner gateways. There the burnt offering was to be washed.", "asv": "And a chamber with the door thereof was by the posts at the gates; there they washed the burnt-offering.", "ylt": "And the chamber and its opening is by the posts of the gates, there they purge the burnt-offering.", "dra": "And at every chamber was a door in the forefronts of the gates: there they washed the holocaust.", "bbe": "And there was a room with a door in the covered way of the doorway, where the burned offering was washed.", "geneva": "And euery chamber, and the entrie thereof was vnder the postes of the gates: there they washed the burnt offring.", "wycliffe": "And bi alle tresories a dore was in the frountis of yatis; and there thei waischiden brent sacrifice.", "rotherham": "And there was a chamber with its entrance, within the projections at the gates,— there, shall they rinse the ascending-sacrifice,", "darby": "And there was a cell and its entry by the posts of the gates; there they rinsed the burnt-offering.", "twenty": "", "jps": "And a chamber with the entry thereof was by the posts at the gates; there was the burnt-offering to be washed.", "acv": "And a chamber with the door of it was by the posts at the gates. There they washed the burnt offering.", "anderson": "", "haweis": "", "noyes": "And a room with its doors was by the borders of the gates, where they washed the burnt-offering.", "webster": "And the chambers and its entries [were] by the posts of the gates, where they washed the burnt-offering.", "vulgate": "et per singula gazofilacia ostium in frontibus portarum ibi lavabunt holocaustum;", "brenton": "Its chambers and its door-ways, and its porches at the second gate served as a drain,"}}, {"v": 39, "ref": "40:39", "o": "וּ/בְ/אֻלָ֣ם הַ/שַּׁ֗עַר שְׁנַ֤יִם שֻׁלְחָנוֹת֙ מִ/פּ֔וֹ וּ/שְׁנַ֥יִם שֻׁלְחָנ֖וֹת מִ/פֹּ֑ה לִ/שְׁח֤וֹט אֲלֵי/הֶם֙ הָ/עוֹלָ֔ה וְ/הַ/חַטָּ֖את וְ/הָ/אָשָֽׁם", "en": {"kjv": "And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt offering and the sin offering and the trespass offering.", "web": "In the porch of the gate were two tables on this side, and two tables on that side, on which to kill the burnt offering, the sin offering, and the trespass offering.", "bsb": "Inside the portico of the gateway were two tables on each side, on which the burnt offerings, sin offerings, and guilt offerings were to be slaughtered.", "asv": "And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt-offering and the sin-offering and the trespass-offering.", "ylt": "And in the porch of the gate are two tables on this side, and two tables on that side, to slaughter on them the burnt-offering, and the sin-offering, and the guilt-offering;", "dra": "And in the porch of the gate were two tables on this side, and two tables on that side: that the holocaust, and the sin offering, and the trespass offering might be slain thereon.", "bbe": "And in the covered way of the doorway there were two tables on this side and two tables on that side, on which the burned offering and the sin-offering and the offering for error were put to death:", "geneva": "And in the porch of the gate stoode two tables on this side, and two tables on that side, vpon the which they slew the burnt offring, and the sinne offring, and the trespas offring.", "wycliffe": "And in the porche of the yate weren twei boordis on this side, and twei boordis on that side, that brent sacrifice be offrid on tho, `bothe for synne and for trespasse.", "rotherham": "And in the porch of the gate, were two tables on this side, and two tables, on that side,—to slay thereon the ascending-sacrifice, and the sin-bearer, and the guilt-bearer.", "darby": "And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt-offering and the sin-offering and the trespass-offering.", "twenty": "", "jps": "And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt-offering and the sin-offering and the guilt-offering.", "acv": "And in the porch of the gate were two tables on this side, and two tables on that side, to kill on it the burnt offering and the sin offering and the trespass offering.", "anderson": "", "haweis": "", "noyes": "And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt-offering, and the sin-offering, and the trespass-offering.", "webster": "And in the porch of the gate [were] two tables on this side, and two tables on that side, to slay upon it the burnt-offering and the sin-offering and the trespass-offering.", "vulgate": "et in vestibulo portae duae mensae hinc et duae mensae inde ut immoletur super eas holocaustum et pro peccato et pro delicto;", "brenton": "that they might slay in it the sin-offerings, and the trespass-offerings."}}, {"v": 40, "ref": "40:40", "o": "וְ/אֶל הַ/כָּתֵ֣ף מִ/ח֗וּצָ/ה לָ/עוֹלֶה֙ לְ/פֶ֨תַח֙ הַ/שַּׁ֣עַר הַ/צָּפ֔וֹנָ/ה שְׁנַ֖יִם שֻׁלְחָנ֑וֹת וְ/אֶל הַ/כָּתֵ֣ף הָ/אַחֶ֗רֶת אֲשֶׁר֙ לְ/אֻלָ֣ם הַ/שַּׁ֔עַר שְׁנַ֖יִם שֻׁלְחָנֽוֹת", "en": {"kjv": "And at the side without, as one goeth up to the entry of the north gate, were two tables; and on the other side, which was at the porch of the gate, were two tables.", "web": "On the one side outside, as one goes up to the entry of the gate toward the north, were two tables; and on the other side, which belonged to the porch of the gate, were two tables.", "bsb": "Outside, as one goes up to the entrance of the north gateway, there were two tables on one side and two more tables on the other side of the gate’s portico.", "asv": "And on the one side without, as one goeth up to the entry of the gate toward the north, were two tables; and on the other side, which belonged to the porch of the gate, were two tables.", "ylt": "and at the side without, at the going up to the opening of the north gate, are two tables; and at the other side that is at the porch of the gate, are two tables;", "dra": "And on the outward side, which goeth up to the entry of the gate that looketh toward the north, were two tables: and at the other side before the porch of the gate were two tables,", "bbe": "On the outer side, to the north, as one goes up to the opening of the doorway, were two tables.", "geneva": "And at the side beyond the steppes, at the entry of the North gate stoode two tables, and on the other side, which was at the porch of the gate were two tables.", "wycliffe": "And at the outermore side, which stieth to the dore of the yate that goith to the north, weren twei boordis; and at `the tother side, bifor the porche of the yate, weren twei boordis.", "rotherham": "And at the side without, in ascending to the entrance of the north gate, were two tables,—and at the other side which pertaineth to the porch of the gate, were two tables.", "darby": "And at the side without, at the ascent to the entry of the north gate, were two tables; and on the other side, which was at the porch of the gate, were two tables:", "twenty": "", "jps": "And on the one side without, as one goeth up to the entry of the gate toward the north, were two tables; and on the other side of the porch of the gate were two tables.", "acv": "And on the one side outside, at the going up to the entry of the gate toward the north, were two tables, and on the other side, which belonged to the porch of the gate, were two tables.", "anderson": "", "haweis": "", "noyes": "And at the side without, as one goeth up to the entrance of the north gate, were two tables; and on the other side, which was at the porch of the gate, were two tables;", "webster": "And at the side without, as one goeth up to the entry of the north gate, [were] two tables; and on the other side, which [was] at the porch of the gate, [were] two tables.", "vulgate": "et ad latus exterius quod ascendit ad ostium portae quae pergit ad aquilonem duae mensae et ad latus alterum ante vestibulum portae duae mensae;", "brenton": "And behind the drain for the whole-burnt-offerings at the north gate, two tables eastward behind the second gate; and behind the porch of the gate two tables eastward."}}, {"v": 41, "ref": "40:41", "o": "אַרְבָּעָ֨ה שֻׁלְחָנ֜וֹת מִ/פֹּ֗ה וְ/אַרְבָּעָ֧ה שֻׁלְחָנ֛וֹת מִ/פֹּ֖ה לְ/כֶ֣תֶף הַ/שָּׁ֑עַר שְׁמוֹנָ֥ה שֻׁלְחָנ֖וֹת אֲלֵי/הֶ֥ם יִשְׁחָֽטוּ", "en": {"kjv": "Four tables were on this side, and four tables on that side, by the side of the gate; eight tables, whereupon they slew their sacrifices.", "web": "Four tables were on this side, and four tables on that side, by the side of the gate; eight tables, whereupon they killed the sacrifices.", "bsb": "So there were four tables inside the gateway and four outside—eight tables in all—on which the sacrifices were to be slaughtered.", "asv": "Four tables were on this side, and four tables on that side, by the side of the gate; eight tables, whereupon they slew the sacrifices.", "ylt": "four tables are on this side, and four tables on that side, at the side of the gate, eight tables on which they slaughter.", "dra": "Four tables were on this side, and four tables on that side at the sides of the gate were eight tables, upon which they slew the victims.", "bbe": "There were four tables on one side and four tables on the other, by the side of the doorway; eight tables, on which they put to death the beasts for the offerings.", "geneva": "Foure tables were on this side, and foure tables on that side by the side of the gate, euen eight tables whereupon they slew their sacrifice.", "wycliffe": "Foure boordis on this side, and foure boordis on that side; bi the sidis of the yate weren eiyte boordis, on whiche thei offriden.", "rotherham": "Four tables on this side and four tables on that side by the side of the gate,-eight tables whereupon they shall slay.", "darby": "four tables on this side, and four tables on that side, by the side of the gate, — eight tables, whereon they slew [the sacrifice],", "twenty": "", "jps": "Four tables were on this side, and four tables on that side, by the side of the gate; eight tables, whereupon to slay the sacrifices.", "acv": "Four tables were on this side, and four tables on that side, by the side of the gate, eight tables, upon which they killed the sacrifices.", "anderson": "", "haweis": "", "noyes": "four tables were on this side, and four tables on that side; on the other side of the gate eight tables, whereon they slew their sacrifices.", "webster": "Four tables [were] on this side, and four tables on that side, by the side of the gate; eight tables, upon which they slew [their sacrifices].", "vulgate": "quattuor mensae hinc et quattuor mensae inde per latera portae octo mensae erunt super quas immolabunt;", "brenton": "Four on one side and four on the other side behind the gate; upon them they kill the victims, in front of the eight tables of sacrifices."}}, {"v": 42, "ref": "40:42", "o": "וְ/אַרְבָּעָה֩ שֻׁלְחָנ֨וֹת לָ/עוֹלָ֜ה אַבְנֵ֣י גָזִ֗ית אֹרֶךְ֩ אַמָּ֨ה אַחַ֤ת וָ/חֵ֨צִי֙ וְ/רֹ֨חַב אַמָּ֤ה אַחַת֙ וָ/חֵ֔צִי וְ/גֹ֖בַהּ אַמָּ֣ה אֶחָ֑ת אֲלֵי/הֶ֗ם וְ/יַנִּ֤יחוּ אֶת הַ/כֵּלִים֙ אֲשֶׁ֨ר יִשְׁחֲט֧וּ אֶת הָ/עוֹלָ֛ה בָּ֖/ם וְ/הַ/זָּֽבַח", "en": {"kjv": "And the four tables were of hewn stone for the burnt offering, of a cubit and an half long, and a cubit and an half broad, and one cubit high: whereupon also they laid the instruments wherewith they slew the burnt offering and the sacrifice.", "web": "There were four tables for the burnt offering, of cut stone, a cubit and a half long, and a cubit and a half broad, and one cubit high; whereupon they laid the instruments with which they killed the burnt offering and the sacrifice.", "bsb": "There were also four tables of dressed stone for the burnt offering, each a cubit and a half long, a cubit and a half wide, and a cubit high. On these were placed the utensils used to slaughter the burnt offerings and the other sacrifices.", "asv": "And there were four tables for the burnt-offering, of hewn stone, a cubit and a half long, and a cubit and a half broad, and one cubit high; whereupon they laid the instruments wherewith they slew the burnt-offering and the sacrifice.", "ylt": "And the four tables for burnt-offering are of hewn stone: the length one cubit and a half, and the breadth one cubit and a half, and the height one cubit: on them they place the instruments with which they slaughter the burnt-offering and the sacrifice.", "dra": "And the four tables for the holocausts were made of square stones: one cubit and a half long, and one cubit and a half broad, and one cubit high: to lay the vessels upon, in which the holocaust and the victim is slain.", "bbe": "And there were four tables for the burned offering, made of cut stone, one and a half cubits long, one and a half cubits wide and a cubit high, where the instruments were placed which were used for putting to death the burned offering and the beasts for the offerings.", "geneva": "And the foure tables were of hewen stone for the burnt offering, of a cubite and an halfe long, and a cubite and an halfe broade, and one cubite hie: whereupon also they layde the instruments wherewith they slew the burnt offring and the sacrifice.", "wycliffe": "Forsothe foure boordis to brent sacrifice weren bildid of square stoonys, in the lengthe of o cubit and an half, and in the breed of o cubit and an half, and in the hiythe of o cubit; on whiche boordis thei schulen sette vessels, in whiche brent sacrifice and slayn sacrifice is offrid.", "rotherham": "And the four tables for the ascending-offering: were of hewn stone. in length, one cubit and a half, and in breadth, one cubit and a half, and in height, one cubit,—that thereon, they may lay the instruments wherewith they shall slay the ascending-offering and the sacrifice.", "darby": "— and at the ascent, four tables of hewn stone, of a cubit and a half long, and a cubit and a half broad, and one cubit high; whereon also they laid the instruments with which they slew the burnt-offering and the sacrifice.", "twenty": "", "jps": "Moreover there were four tables for the burnt-offering, of hewn stone, a cubit and a half long, and a cubit and a half broad, and one cubit high, whereupon to lay the instruments wherewith the burnt-offering and the sacrifice are slain.", "acv": "And there were four tables for the burnt offering, of hewn stone, a cubit and a half long, and a cubit and a half broad, and one cubit high, upon which they laid the instruments of which they killed the burnt offering and the sacrifice.", "anderson": "", "haweis": "", "noyes": "And the four tables for the burnt-offering were of hewn stone; their length was a cubit and a half, and their breadth a cubit and a half, and their height a cubit. Thereon they laid the instruments with which they slew the burnt-offering and the sacrifice.", "webster": "And the four tables [were] of hewn stone for the burnt-offering, of a cubit and a half long, and a cubit and a half broad, and one cubit high: upon which also they laid the instruments with which they slew the burnt-offering and the sacrifice.", "vulgate": "quattuor autem mensae ad holocaustum de lapidibus quadris extructae longitudine cubiti unius et dimidii et latitudine cubiti unius et dimidii et altitudine cubiti unius super quas ponant vasa in quibus immolatur holocaustum et victima;", "brenton": "And there were four tables of hewn stone for whole-burnt-offerings, the breadth of them was a cubit and a half, and the length of them two cubits and a half, and their height was a cubit: on them they shall place the instruments with which they slay there the whole-burnt-offerings and the victims."}}, {"v": 43, "ref": "40:43", "o": "וְ/הַֽ/שְׁפַתַּ֗יִם טֹ֧פַח אֶחָ֛ד מוּכָנִ֥ים בַּ/בַּ֖יִת סָבִ֣יב סָבִ֑יב וְ/אֶל הַ/שֻּׁלְחָנ֖וֹת בְּשַׂ֥ר הַ/קָּרְבָֽן", "en": {"kjv": "And within were hooks, an hand broad, fastened round about: and upon the tables was the flesh of the offering.", "web": "The hooks, a hand breadth long, were fastened within all around: and on the tables was the flesh of the offering.", "bsb": "The double-pronged hooks, each a handbreadth long, were fastened all around the inside of the room, and the flesh of the offering was to be placed on the tables.", "asv": "And the hooks, a handbreadth long, were fastened within round about: and upon the tables was the flesh of the oblation.", "ylt": "And the boundaries are one handbreadth, prepared within all round about: and on the tables is the flesh of the offering.", "dra": "And the borders of them were of one handbreadth, turned inwards round about: and upon the tables was the flesh of the offering.", "bbe": "And they had edges all round as wide as a man's hand: and on the tables was the flesh of the offerings.", "geneva": "And within were borders an hand broade, fastened round about, and vpon the tables lay the flesh of the offring.", "wycliffe": "And the brenkis of tho boordis ben of oon handibreede, and ben bowid ayen with ynne bi cumpas; forsothe on the boordis weren fleischis of offryng.", "rotherham": "And there were hooks of three hand-breadth fastened within round about on every side,—and upon the tables, the flesh of the offering.", "darby": "And the double hooks of a hand breadth were fastened round about within; and upon the tables [they put] the flesh of the offering.", "twenty": "", "jps": "And the slabs, a handbreadth long, were fastened within round about; and upon the tables was to be the flesh of the offering.", "acv": "And the hooks, a handbreadth long, were fastened inside round about. And upon the tables was the flesh of the oblation.", "anderson": "", "haweis": "", "noyes": "And there were edging-boards of a handbreadth, prepared within round about; and upon the tables was the flesh of the offering.", "webster": "And within [were] hooks, a hand broad, fastened around: and upon the tables [was] the flesh of the offering.", "vulgate": "et labia earum palmi unius reflexa intrinsecus per circuitum super mensas autem carnes oblationis;", "brenton": "And they shall have within a border of hewn stone round about of a span broad, and over the tables above screens for covering them from the wet and from the heat."}}, {"v": 44, "ref": "40:44", "o": "וּ/מִ/חוּצָ/ה֩ לַ/שַּׁ֨עַר הַ/פְּנִימִ֜י לִֽשְׁכ֣וֹת שָׁרִ֗ים בֶּ/חָצֵ֤ר הַ/פְּנִימִי֙ אֲשֶׁ֗ר אֶל כֶּ֨תֶף֙ שַׁ֣עַר הַ/צָּפ֔וֹן וּ/פְנֵי/הֶ֖ם דֶּ֣רֶךְ הַ/דָּר֑וֹם אֶחָ֗ד אֶל כֶּ֨תֶף֙ שַׁ֣עַר הַ/קָּדִ֔ים פְּנֵ֖י דֶּ֥רֶךְ הַ/צָּפֹֽן", "en": {"kjv": "And without the inner gate were the chambers of the singers in the inner court, which was at the side of the north gate; and their prospect was toward the south: one at the side of the east gate having the prospect toward the north.", "web": "Outside of the inner gate were rooms for the singers in the inner court, which was at the side of the north gate; and their prospect was toward the south; one at the side of the east gate having the prospect toward the north.", "bsb": "Outside the inner gate, within the inner court, were two chambers, one beside the north gate and facing south, and another beside the south gate and facing north.", "asv": "And without the inner gate were chambers for the singers in the inner court, which was at the side of the north gate; and their prospect was toward the south; one at the side of the east gate having the prospect toward the north.", "ylt": "And on the outside of the inner gate are chambers of the singers, in the inner court, that are at the side of the north gate, and their fronts are southward, one at the side of the east gate hath the front northward.", "dra": "And without the inner gate were the chambers of the singing men in the inner court, which was on the side of the gate that looketh to the north: and their prospect was towards the south, one at the side of the east gate, which looketh toward the north.", "bbe": "And he took me into the inner square, and there were two rooms in the inner square, one at the side of the north doorway, facing south; and one at the side of the south doorway, facing north.", "geneva": "And without the inner gate were ye chambers of the singers in the inner Court, which was at the side of the North gate: and their prospect was towarde the South, and one was at the side of the East gate, hauing the prospect towarde the North.", "wycliffe": "And with out the ynnere yate weren tresories of chauntours, in the ynnere halle, that was in the side of the yate biholdynge to the north; and the faces of tho weren ayens the south weie; oon of the side of the eest yate, that bihelde to the weie of the north.", "rotherham": "And on the outside of the inner gate, were the chambers of the singers in the inner court which was at the side of the north gate, and their front was toward the south,—one, at the side of the south gate, fronting, toward the north.", "darby": "And outside the inner gate were two cells in the inner court, one at the side of the north gate, and its front towards the south; the other was at the side of the south gate, the front towards the north.", "twenty": "", "jps": "And without the inner gate were chambers for the guard in the inner court, which was at the side of the north gate, and their prospect was toward the south; one at the side of the east gate having the prospect toward the north.", "acv": "And outside the inner gate were chambers for the singers in the inner court, which was at the side of the north gate, and their view was toward the south, one at the side of the east gate having the view toward the north.", "anderson": "", "haweis": "", "noyes": "And without the inner gate were rooms for the singers in the inner court; they were at the side of the north gate, and their prospect was toward the south; one at the side of the east gate having the prospect toward the north.", "webster": "And without the inner gate [were] the chambers of the singers in the inner court, which [was] at the side of the north gate; and their prospect [was] towards the south: one at the side of the east gate [having] the prospect towards the north.", "vulgate": "et extra portam interiorem gazofilacia cantorum in atrio interiori quod erat in latere portae respicientis ad aquilonem et facies eorum contra viam australem una ex latere portae orientalis quae respiciebat ad viam aquilonis;", "brenton": "And he brought me into the inner court, and behold there were two chambers in the inner court, one behind the gate looking to the north, turning southward, and one behind the southern gate, but which looks to the north."}}, {"v": 45, "ref": "40:45", "o": "וַ/יְדַבֵּ֖ר אֵלָ֑/י זֹ֣ה הַ/לִּשְׁכָּ֗ה אֲשֶׁ֤ר פָּנֶ֨י/הָ֙ דֶּ֣רֶךְ הַ/דָּר֔וֹם לַ/כֹּ֣הֲנִ֔ים שֹׁמְרֵ֖י מִשְׁמֶ֥רֶת הַ/בָּֽיִת", "en": {"kjv": "And he said unto me, This chamber, whose prospect is toward the south, is for the priests, the keepers of the charge of the house.", "web": "He said to me, This room, whose prospect is toward the south, is for the priests, the keepers of the duty of the house;", "bsb": "Then the man said to me: “The chamber that faces south is for the priests who keep charge of the temple,", "asv": "And he said unto me, This chamber, whose prospect is toward the south, is for the priests, the keepers of the charge of the house;", "ylt": "And he speaketh unto me: `This chamber, whose front is southward, is for priests keeping charge of the house;", "dra": "And he said to me: This chamber, which looketh toward the south shall be for the priests that watch in the wards of the temple.", "bbe": "And he said to me, This room, facing south, is for the priests who have the care of the house.", "geneva": "And he said vnto me, This chamber whose prospect is towarde the South, is for the Priestes that haue the charge to keepe the house.", "wycliffe": "And he seide to me, This treserie, that biholdith the south weie, is of the prestis that waken in the kepyngis of the temple,", "rotherham": "Then spake he unto me saying, This chamber whose front is toward the south, is for the priests keeping the charge of the house;", "darby": "And he said unto me, This cell whose front is towards the south is for the priests, the keepers of the charge of the house.", "twenty": "", "jps": "And he said unto me: 'This chamber, whose prospect is toward the south, is for the priests, the keepers of the charge of the house.", "acv": "And he said to me, This chamber, whose view is toward the south, is for the priests, the keepers of the charge of the house.", "anderson": "", "haweis": "", "noyes": "And he said to me, This room, whose prospect is toward the south, is for the priests that keep the charge of the house.", "webster": "And he said to me, This chamber, whose prospect [is] towards the south, [is] for the priests, the keepers of the charge of the house.", "vulgate": "et dixit ad me hoc est gazofilacium quod respicit viam meridianam sacerdotum qui excubant in custodiis templi;", "brenton": "And he said to me, This chamber that looks to the south, is for the priests that keep the charge of the house."}}, {"v": 46, "ref": "40:46", "o": "וְ/הַ/לִּשְׁכָּ֗ה אֲשֶׁ֤ר פָּנֶ֨י/הָ֙ דֶּ֣רֶךְ הַ/צָּפ֔וֹן לַ/כֹּ֣הֲנִ֔ים שֹׁמְרֵ֖י מִשְׁמֶ֣רֶת הַ/מִּזְבֵּ֑חַ הֵ֣מָּה בְנֵֽי צָד֗וֹק הַ/קְּרֵבִ֧ים מִ/בְּנֵֽי לֵוִ֛י אֶל יְהוָ֖ה לְ/שָׁרְתֽ/וֹ", "en": {"kjv": "And the chamber whose prospect is toward the north is for the priests, the keepers of the charge of the altar: these are the sons of Zadok among the sons of Levi, which come near to the Lord to minister unto him.", "web": "and the room whose prospect is toward the north is for the priests, the keepers of the duty of the altar: these are the sons of Zadok, who from among the sons of Levi come near to Yahweh to minister to him.", "bsb": "and the chamber that faces north is for the priests who keep charge of the altar. These are the sons of Zadok, the only Levites who may approach the LORD to minister before Him.”", "asv": "and the chamber whose prospect is toward the north is for the priests, the keepers of the charge of the altar: these are the sons of Zadok, who from among the sons of Levi come near to Jehovah to minister unto him.", "ylt": "and the chamber, whose front is northward, is for priests keeping charge of the altar: they are sons of Zadok, who are drawing near of the sons of Levi unto Jehovah, to serve Him.'", "dra": "But the chamber that looketh towards the north shall be for the priests that watch over the ministry of the altar. These are the sons of Sadoc, who among the sons of Levi, come near to the Lord, to minister to him.", "bbe": "And the room facing north is for the priests who have the care of the altar: these are the sons of Zadok, who, from among the sons of Levi, come near to the Lord to do the work of his house.", "geneva": "And the chamber whose prospect is toward the North, is for the Priestes that haue the charge to keepe the altar: these are the sonnes of Zadok among ye sonnes of Leui which may come neere to the Lord to minister vnto him.", "wycliffe": "Sotheli the tresorye that biholdith to the weie of the north, schal be of the preestis that waken to the seruice of the auter; these ben the sones of Sadoch, whiche of the sones of Leuy neiyen to the Lord, for to mynystre to hym.", "rotherham": "and the chamber whose front is towards the north is for the priests keeping the charge of the altar,-the same are the sons of Zadok—who draw near from among the sons of Levi unto Yahweh. to wait upon him.", "darby": "And the cell whose front is toward the north is for the priests, the keepers of the charge of the altar. These are the sons of Zadok, those who, from among the sons of Levi, approach unto Jehovah to minister unto him.", "twenty": "", "jps": "And the chamber whose prospect is toward the north is for the priests, the keepers of the charge of the altar; these are the sons of Zadok, who from among the sons of Levi come near to HaShem to minister unto Him.'", "acv": "And the chamber whose view is toward the north is for the priests, the keepers of the charge of the altar. These are the sons of Zadok, who from among the sons of Levi come near to Jehovah to minister to him.", "anderson": "", "haweis": "", "noyes": "And the room whose prospect is toward the north is for the priests that keep the charge of the altar. These are the sons of Zadok, who, among the sons of Levi, come near to Jehovah to minister to him.", "webster": "And the chamber whose prospect [is] towards the north [is] for the priests, the keepers of the charge of the altar: these [are] the sons of Zadok among the sons of Levi, who come near to the LORD to minister to him.", "vulgate": "porro gazofilacium quod respicit ad viam aquilonis sacerdotum erit qui excubant ad ministerium altaris isti sunt filii Sadoc qui accedunt de filiis Levi ad Dominum ut ministrent ei;", "brenton": "And the chamber that looks to the north is for the priests that keep the charge of the altar: they are the sons of Sadduc, those of the tribe of Levi who draw near to the Lord to serve him."}}, {"v": 47, "ref": "40:47", "o": "וַ/יָּ֨מָד אֶת הֶ/חָצֵ֜ר אֹ֣רֶךְ מֵאָ֣ה אַמָּ֗ה וְ/רֹ֛חַב מֵאָ֥ה אַמָּ֖ה מְרֻבָּ֑עַת וְ/הַ/מִּזְבֵּ֖חַ לִ/פְנֵ֥י הַ/בָּֽיִת", "en": {"kjv": "So he measured the court, an hundred cubits long, and an hundred cubits broad, foursquare; and the altar that was before the house.", "web": "He measured the court, one hundred cubits long, and a hundred cubits broad, square; and the altar was before the house.", "bsb": "Next he measured the court. It was square, a hundred cubits long and a hundred cubits wide. And the altar was in front of the temple.", "asv": "And he measured the court, a hundred cubits long, and a hundred cubits broad, foursquare; and the altar was before the house.", "ylt": "And he measureth the court: the length a hundred cubits, and the breadth a hundred cubits, square, and the altar is before the house.", "dra": "And he measured the court a hundred cubits long, and a hundred cubits broad foursquare: and the altar that was before the face of the temple.", "bbe": "And he took the measure of the open square, a hundred cubits long and a hundred cubits wide, being square; and the altar was in front of the house.", "geneva": "So he measured the court, an hundreth cubites long, and an hundreth cubits broad, eue foure square: likewise the altar that was before ye house.", "wycliffe": "And he mat the halle, the lengthe of an hundrid cubitis, and the breede of an hundrid cubitis, bi square, and the auter bifore the face of the temple.", "rotherham": "Then measured he the court, the length, a hundred cubits, and the breadth, a hundred cubits foursquare,—with the altar before the house.", "darby": "And he measured the court, the length a hundred cubits, and the breadth a hundred cubits, four square: and the altar was before the house.", "twenty": "", "jps": "And he measured the court, a hundred cubits long, and a hundred cubits broad, foursquare; and the altar was before the house.", "acv": "And he measured the court, a hundred cubits long, and a hundred cubits broad, foursquare. And the altar was before the house.", "anderson": "", "haweis": "", "noyes": "Then he measured the court; its length was a hundred cubits, and its breadth a hundred cubits, being square. And the altar stood before the house.", "webster": "So he measured the court, a hundred cubits long, and a hundred cubits broad, foursquare; and the altar [that was] before the house.", "vulgate": "et mensus est atrium longitudine centum cubitorum et latitudine centum cubitorum per quadrum et altare ante faciem templi;", "brenton": "And he measured the court, the length whereof was a hundred cubits, and the breadth a hundred cubits, on its four sides; and the altar in front of the house."}}, {"v": 48, "ref": "40:48", "o": "וַ/יְבִאֵ/נִי֮ אֶל אֻלָ֣ם הַ/בַּיִת֒ וַ/יָּ֨מָד֙ אֵ֣ל אֻלָ֔ם חָמֵ֤שׁ אַמּוֹת֙ מִ/פֹּ֔ה וְ/חָמֵ֥שׁ אַמּ֖וֹת מִ/פֹּ֑ה וְ/רֹ֣חַב הַ/שַּׁ֔עַר שָׁלֹ֤שׁ אַמּוֹת֙ מִ/פּ֔וֹ וְ/שָׁלֹ֥שׁ אַמּ֖וֹת מִ/פּֽוֹ", "en": {"kjv": "And he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side: and the breadth of the gate was three cubits on this side, and three cubits on that side.", "web": "Then he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side: and the breadth of the gate was three cubits on this side, and three cubits on that side.", "bsb": "Then he brought me to the portico of the temple and measured the side pillars of the portico to be five cubits on each side. The width of the gateway was fourteen cubits and its sidewalls were three cubits on either side.", "asv": "Then he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side: and the breadth of the gate was three cubits on this side, and three cubits on that side.", "ylt": "And he bringeth me in unto the porch of the house, and he measureth the post of the porch, five cubits on this side, and five cubits on that side, and the breadth of the gate, three cubits on this side, and three cubits on that side;", "dra": "And he brought me into the porch of the temple: and he measured the porch five cubits on this side, and five cubits on that side: and the breadth of the gate three cubits on this side, and three cubits on that side.", "bbe": "Then he took me to the covered way before the house, and took the measure of its uprights, five cubits on one side and five cubits on the other: and the doorway was fourteen cubits wide; and the side-walls of the doorway were three cubits on one side and three cubits on the other.", "geneva": "And hee brought mee to the porch of the house, and measured the postes of the porch, fiue cubites on this side, and fiue cubites on that side: and the breadth of the gate was three cubites on this side, and three cubites on that side.", "wycliffe": "And he ledde me in to the porche of the temple; and he mat the porche bi fyue cubitis on this side, and bi fyue cubitis on that side; and he mat the breede of the yate, of thre cubitis on this side, and of thre cubitis on that side.", "rotherham": "And when he brought me unto the porch of the house, then measured he the projection of the porch, five cubits on this side, and five cubits on that side,—and the breadth of the gate, was three cubits on this side, and three cubits on that side:", "darby": "And he brought me to the porch of the house; and he measured the post of the porch, five cubits on this side, and five cubits on that side; and the breadth of the gate, three cubits on this side, and three cubits on that side.", "twenty": "", "jps": "Then he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side; and the breadth of the gate was three cubits on this side, and three cubits on that side.", "acv": "Then he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side. And the breadth of the gate was three cubits on this side, and three cubits on that side.", "anderson": "", "haweis": "", "noyes": "Then he brought me to the porch of the temple, and he measured the door-border of the porch, five cubits on this side, and five cubits on that side. And the breadth of the gate was three cubits on this side, and three cubits on that side.", "webster": "And he brought me to the porch of the house, and measured [each] post of the porch, five cubits on this side, and five cubits on that side: and the breadth of the gate [was] three cubits on this side, and three cubits on that side.", "vulgate": "et introduxit me in vestibulum templi et mensus est vestibulum quinque cubitis hinc et quinque cubitis inde et latitudinem portae trium cubitorum hinc et trium cubitorum inde;", "brenton": "And he brought me into the porch of the house; and he measured the post of the porch, the breadth was five cubits on one side and five cubits on the other side; and the breadth of the door was fourteen cubits, and the side-pieces of the door of the porch were three cubits on one side, and three cubits on the other side."}}, {"v": 49, "ref": "40:49", "o": "אֹ֣רֶךְ הָ/אֻלָ֞ם עֶשְׂרִ֣ים אַמָּ֗ה וְ/רֹ֨חַב֙ עַשְׁתֵּ֣י עֶשְׂרֵ֣ה אַמָּ֔ה וּ/בַֽ/מַּעֲל֔וֹת אֲשֶׁ֥ר יַעֲל֖וּ אֵלָ֑י/ו וְ/עַמֻּדִים֙ אֶל הָ֣/אֵילִ֔ים אֶחָ֥ד מִ/פֹּ֖ה וְ/אֶחָ֥ד מִ/פֹּֽה", "en": {"kjv": "The length of the porch was twenty cubits, and the breadth eleven cubits; and he brought me by the steps whereby they went up to it: and there were pillars by the posts, one on this side, and another on that side.", "web": "The length of the porch was twenty cubits, and the breadth eleven cubits; even by the steps by which they went up to it: and there were pillars by the posts, one on this side, and another on that side.", "bsb": "The portico was twenty cubits wide and twelve cubits deep, and ten steps led up to it. There were columns by the side pillars, one on each side.", "asv": "The length of the porch was twenty cubits, and the breadth eleven cubits; even by the steps whereby they went up to it: and there were pillars by the posts, one on this side, and another on that side.", "ylt": "the length of the porch twenty cubits, and the breadth eleven cubits; and by the steps whereby they go up unto it: and pillars are at the posts, one on this side, and one on that side.", "dra": "And the length of the porch was twenty cubits, and the breadth eleven cubits, and there were eight steps to go up to it. And there were pillars in the fronts: one on this side, and another on that side.", "bbe": "The covered way was twenty cubits long and twelve cubits wide, and they went up to it by ten steps; and there were pillars by the uprights, one on one side and one on the other.", "geneva": "The length of the porch was twentie cubites, and ye breadth eleuen cubites, and he brought me by the steps whereby they went vp to it, and there were pillars by the postes, one on this side, and another on that side.", "wycliffe": "But he mat the lengthe of the porche of twenti cubitis, and the breede of eleuene cubitis, and bi eiyte degrees me stiede to it; and pileris weren in the frountis, oon on this side, and `another on that side.", "rotherham": "the length of the porch was twenty cubits and the breadth twelve cubits, and by ten steps they ascend into it,- and there were pillars against the projections, one on this side, and one on that side.", "darby": "The length of the porch was twenty cubits, and the breadth eleven cubits, even by the steps whereby they went up to it; and there were pillars by the posts, one on this side, and one on that side.", "twenty": "", "jps": "The length of the porch was twenty cubits, and the breadth eleven cubits; and it was by steps that it was ascended; and there were pillars by the posts, one on this side, and another on that side.", "acv": "The length of the porch was twenty cubits, and the breadth eleven cubits, even by the steps by which they went up to it. And there were pillars by the posts, one on this side, and another on that side.", "anderson": "", "haweis": "", "noyes": "The length of the porch was twenty cubits, and the breadth eleven cubits; and they went up to it by steps. And there were columns by the door-border, one on this side, and another on that side.", "webster": "The length of the porch [was] twenty cubits, and the breadth eleven cubits; and [he brought me] by the steps by which they went up to it: and [there were] pillars by the posts, one on this side, and another on that side.", "vulgate": "longitudinem autem vestibuli viginti cubitorum et latitudinem undecim cubitorum et octo gradibus ascendebatur ad eam et columnae erant in frontibus una hinc et altera inde;", "brenton": "And the length of the porch was twenty cubits, and the breadth twelve cubits; and they went up to it by ten steps; and there were pillars to the porch, one on this side and one on that side."}}]}, {"c": 41, "verses": [{"v": 1, "ref": "41:1", "o": "וַ/יְבִיאֵ֖/נִי אֶל הַ/הֵיכָ֑ל וַ/יָּ֣מָד אֶת הָ/אֵילִ֗ים שֵׁשׁ אַמּ֨וֹת רֹ֧חַב מִ/פּ֛וֹ וְ/שֵׁשׁ אַמּֽוֹת רֹ֥חַב מִ/פּ֖וֹ רֹ֥חַב הָ/אֹֽהֶל", "en": {"kjv": "Afterward he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tabernacle.", "web": "He brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tent.", "bsb": "Then the man brought me into the outer sanctuary and measured the side pillars to be six cubits wide on each side.", "asv": "And he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tabernacle.", "ylt": "And he bringeth me in unto the temple, and he measureth the posts, six cubits the breadth on this side, and six cubits the breadth on that side--the breadth of the tent.", "dra": "And he brought me into the temple, and he measured the fronts six cubits broad on this side, and six cubits on that side, the breadth of the tabernacle.", "bbe": "And he took me to the Temple, and took the measure of the uprights, six cubits wide on one side and six cubits wide on the other.", "geneva": "Afterward, hee brought mee to the Temple, and measured the postes, sixe cubites broade on the one side, and sixe cubites broad on the other side, which was the breadth of the Tabernacle.", "wycliffe": "And he ledde me in to the temple, and he mat the frountis, sixe cubitis of breede on this side, and sixe cubitis of breede on that side, the breede of the tabernacle.", "rotherham": "Then he took me unto the temple,—and measured the projection six cubits broad on this side and six cubits broad on that side, the breadth of the tent.", "darby": "And he brought me to the temple; and he measured the posts, six cubits broad on the one side, and six cubits broad on the other side, the breadth of the tent.", "twenty": "", "jps": "And he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tent.", "acv": "And he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tabernacle.", "anderson": "", "haweis": "", "noyes": "Afterwards he brought me to the temple; and he measured the projecting wall-pillars, six cubits broad on this side, and six cubits broad on that side, according to the breadth of the house.", "webster": "Afterward he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, [which was] the breadth of the tabernacle.", "vulgate": "et introduxit me in templum et mensus est frontes sex cubitos latitudinis hinc et sex cubitos latitudinis inde latitudinem tabernaculi;", "brenton": "And he brought me into the temple, the porch of which he measured, six cubits the breadth on one side, and six cubits the breadth of the porch on the other side."}}, {"v": 2, "ref": "41:2", "o": "וְ/רֹ֣חַב הַ/פֶּתַח֮ עֶ֣שֶׂר אַמּוֹת֒ וְ/כִתְפ֣וֹת הַ/פֶּ֔תַח חָמֵ֤שׁ אַמּוֹת֙ מִ/פּ֔וֹ וְ/חָמֵ֥שׁ אַמּ֖וֹת מִ/פּ֑וֹ וַ/יָּ֤מָד אָרְכּ/וֹ֙ אַרְבָּעִ֣ים אַמָּ֔ה וְ/רֹ֖חַב עֶשְׂרִ֥ים אַמָּֽה", "en": {"kjv": "And the breadth of the door was ten cubits; and the sides of the door were five cubits on the one side, and five cubits on the other side: and he measured the length thereof, forty cubits: and the breadth, twenty cubits.", "web": "The breadth of the entrance was ten cubits; and the sides of the entrance were five cubits on the one side, and five cubits on the other side: and he measured its length, forty cubits, and the breadth, twenty cubits.", "bsb": "The width of the entrance was ten cubits, and the sides of the entrance were five cubits on each side. He also measured the length of the outer sanctuary to be forty cubits, and the width to be twenty cubits.", "asv": "And the breadth of the entrance was ten cubits; and the sides of the entrance were five cubits on the one side, and five cubits on the other side: and he measured the length thereof, forty cubits, and the breadth, twenty cubits.", "ylt": "And the breadth of the opening is ten cubits; and the sides of the opening are five cubits on this side, and five cubits on that side; and he measureth its length forty cubits, and the breadth twenty cubits.", "dra": "And the breadth of the gate was ten cubits: and the sides of the gate five cubits on this side, and five cubits on that side: and he measured the length thereof forty cubits, and the breadth twenty cubits.", "bbe": "And the door-opening was ten cubits wide; and the side walls of the door-opening were five cubits on one side and five cubits on the other: and it was forty cubits long and twenty cubits wide.", "geneva": "And the breadth of the entrie was tenne cubites, and the sides of the entrie were fiue cubites on the one side, and fiue cubites on the other side, and hee measured the length thereof fourtie cubites, and the breadth twentie cubites.", "wycliffe": "And the breede of the yate was of ten cubitis; and he mat the sidis of the yate bi fyue cubitis on this side, and bi fyue cubitis on that side; and he mat the lengthe therof of fourti cubitis, and the breede of twenti cubitis.", "rotherham": "And the breadth of the entrance was ten cubits and the sides of the entrance were five cubits on this side and five cubits on that side —and he measured the length thereof, forty cubits, and the breadth, twenty cubits.", "darby": "And the breadth of the entry was ten cubits, and the sides of the entry were five cubits on this side, and five cubits on that side; and he measured its length, forty cubits, and the breadth, twenty cubits.", "twenty": "", "jps": "And the breadth of the entrance was ten cubits; and the sides of the entrance were five cubits on the one side, and five cubits on the other side; and he measured the length thereof, forty cubits, and the breadth, twenty cubits.", "acv": "And the breadth of the entrance was ten cubits. And the sides of the entrance were five cubits on the one side, and five cubits on the other side. And he measured the length of it, forty cubits, and the breadth, twenty cubits.", "anderson": "", "haweis": "", "noyes": "And the breadth of the door was ten cubits; and the sides of the door were five cubits on this side; and five cubits on that side. Then he measured the length, forty cubits, and the breadth, twenty cubits.", "webster": "And the breadth of the door [was] ten cubits; and the sides of the door [were] five cubits on the one side, and five cubits on the other side: and he measured the length of it forty cubits: and the breadth, twenty cubits.", "vulgate": "et latitudo portae decem cubitorum erat et latera portae quinque cubitis hinc et quinque cubitis inde et mensus est longitudinem eius quadraginta cubitorum et latitudinem viginti cubitorum;", "brenton": "And the breadth of the gateway was ten cubits, and the side-pieces of the gateway were five cubits on this side, and five cubits on that side: and he measured the length of it, forty cubits, and the breadth, twenty cubits."}}, {"v": 3, "ref": "41:3", "o": "וּ/בָ֣א לִ/פְנִ֔ימָה וַ/יָּ֥מָד אֵֽיל הַ/פֶּ֖תַח שְׁתַּ֣יִם אַמּ֑וֹת וְ/הַ/פֶּ֨תַח֙ שֵׁ֣שׁ אַמּ֔וֹת וְ/רֹ֥חַב הַ/פֶּ֖תַח שֶׁ֥בַע אַמּֽוֹת", "en": {"kjv": "Then went he inward, and measured the post of the door, two cubits; and the door, six cubits; and the breadth of the door, seven cubits.", "web": "Then went he inward, and measured each post of the entrance, two cubits; and the entrance, six cubits; and the breadth of the entrance, seven cubits.", "bsb": "And he went into the inner sanctuary and measured the side pillars at the entrance to be two cubits wide. The entrance was six cubits wide, and the walls on each side were seven cubits wide.", "asv": "Then went he inward, and measured each post of the entrance, two cubits; and the entrance, six cubits; and the breadth of the entrance, seven cubits.", "ylt": "And he hath gone inward, and measureth the post of the opening two cubits, and the opening six cubits, and the breadth of the opening seven cubits.", "dra": "Then going inward he measured the front of the gate two cubits: and the gate six cubits, and the breadth of the gate seven cubits.", "bbe": "And he went inside and took the measure of the uprights of the door-opening, two cubits: and the door-opening, six cubits; and the side-walls of the door-opening were seven cubits on one side and seven cubits on the other.", "geneva": "Then went hee in, and measured the postes of the entrie two cubites, and the entrie sixe cubites, and the breadth of the entrie seuen cubites.", "wycliffe": "And he entride with ynne, and he mat in the frount of the yate twei cubitis; and he mat the yate of sixe cubitis, and the breede of the yate of seuene cubits.", "rotherham": "Then went he inwards, and measured the projection of the entrance, two cubits,—and the entrance itself was six cubits, and the sides of the entrance seven cubits:", "darby": "And he went inwards, and measured the post of the entry, two cubits; and the entry, six cubits; and the breadth of the entry, seven cubits.", "twenty": "", "jps": "Then went he inward, and measured each post of the entrance, two cubits; and the entrance, six cubits; and the breadth of the entrance, seven cubits.", "acv": "Then he went inward, and measured each post of the entrance, two cubits, and the entrance, six cubits, and the breadth of the entrance, seven cubits.", "anderson": "", "haweis": "", "noyes": "And he went inward, and measured the border of the door, two cubits; and the door, six cubits; and the breadth of the door, seven cubits.", "webster": "Then he went inward, and measured the post of the door, two cubits; and the door, six cubits; and the breadth of the door, seven cubits.", "vulgate": "et introgressus intrinsecus mensus est in fronte portae duos cubitos et portam sex cubitorum et latitudinem portae septem cubitorum;", "brenton": "And he went into the inner court, and measured the post of the door, two cubits; and the door, six cubits; and the side-pieces of the door, seven cubits on one side, and seven cubits on the other side."}}, {"v": 4, "ref": "41:4", "o": "וַ/יָּ֨מָד אֶת אָרְכּ֜/וֹ עֶשְׂרִ֣ים אַמָּ֗ה וְ/רֹ֛חַב עֶשְׂרִ֥ים אַמָּ֖ה אֶל פְּנֵ֣י הַֽ/הֵיכָ֑ל וַ/יֹּ֣אמֶר אֵלַ֔/י זֶ֖ה קֹ֥דֶשׁ הַ/קֳּדָשִֽׁים", "en": {"kjv": "So he measured the length thereof, twenty cubits; and the breadth, twenty cubits, before the temple: and he said unto me, This is the most holy place.", "web": "He measured its length, twenty cubits, and the breadth, twenty cubits, before the temple: and he said to me, This is the most holy place.", "bsb": "Then he measured the room adjacent to the inner sanctuary to be twenty cubits long and twenty cubits wide. And he said to me, “This is the Most Holy Place.”", "asv": "And he measured the length thereof, twenty cubits, and the breadth, twenty cubits, before the temple: and he said unto me, This is the most holy place.", "ylt": "And he measureth its length twenty cubits, and the breadth twenty cubits, unto the front of the temple, and he saith unto me, `This is the holy of holies.'", "dra": "And he measured the length thereof twenty cubits, and the breadth twenty cubits, before the face of the temple: and he said to me: This is the holy of holies.", "bbe": "And by his measure it was twenty cubits long and twenty cubits wide in front of the Temple: and he said to me, This is the most holy place.", "geneva": "So he measured the length thereof twentie cubites, and the breadth twentie cubites before the Temple. And he sayde vnto mee, This is the most holy place.", "wycliffe": "And he mat the lengthe therof of twenti cubitis, and the breede of twenti cubitis, bifor the face of the temple.", "rotherham": "so he measured the length thereof twenty cubits, and the breadth twenty cubits, at the front of the temple.", "darby": "And he measured its length, twenty cubits; and the breadth, twenty cubits, before the temple: and he said unto me, This is the most holy [place].", "twenty": "", "jps": "And he measured the length thereof, twenty cubits, and the breadth, twenty cubits, before the temple; and he said unto me: 'This is the most holy place.'", "acv": "And he measured the length of it, twenty cubits, and the breadth, twenty cubits, before the temple. And he said to me, This is the most holy place.", "anderson": "", "haweis": "", "noyes": "Then he measured twenty cubits in length, and twenty cubits in breadth in the temple, and said to me, This is the most holy place.", "webster": "So he measured the length of it twenty cubits; and the breadth, twenty cubits, before the temple: and he said to me, This [is] the most holy [place].", "vulgate": "et mensus est longitudinem eius viginti cubitorum et latitudinem viginti cubitorum ante faciem templi et dixit ad me hoc est sanctum sanctorum;", "brenton": "And he measured the length of the doors, forty cubits; and the breadth, twenty cubits, in front of the temple: and he said, This is the holy of holies."}}, {"v": 5, "ref": "41:5", "o": "וַ/יָּ֥מָד קִֽיר הַ/בַּ֖יִת שֵׁ֣שׁ אַמּ֑וֹת וְ/רֹ֣חַב הַ/צֵּלָע֩ אַרְבַּ֨ע אַמּ֜וֹת סָבִ֧יב סָבִ֛יב לַ/בַּ֖יִת סָבִֽיב", "en": {"kjv": "After he measured the wall of the house, six cubits; and the breadth of every side chamber, four cubits, round about the house on every side.", "web": "Then he measured the wall of the house, six cubits; and the breadth of every side room, four cubits, all around the house on every side.", "bsb": "Next he measured the wall of the temple to be six cubits thick, and the width of each side room around the temple was four cubits.", "asv": "Then he measured the wall of the house, six cubits; and the breadth of every side-chamber, four cubits, round about the house on every side.", "ylt": "And he measureth the wall of the house six cubits, and the breadth of the side-chamber four cubits, all round the house round about.", "dra": "And he measured the wall of the house six cubits: and the breadth of every side chamber four cubits round about the house on every side.", "bbe": "Then he took the measure of the wall of the house, which was six cubits; and of the side-rooms round the house, which were four cubits wide.", "geneva": "After, he measured the wall of the house, sixe cubites, and the breadth of euery chamber foure cubites rounde about the house, on euery side.", "wycliffe": "And he seide to me, This is the hooli thing of hooli thingis. And he mat the wal of the hous of sixe cubitis, and the breede of the side of foure cubitis, on ech side bi cumpas of the hous.", "rotherham": "Then said he unto me This! is the holy of holies. Then measured he the wall of the house six cubits,—and the breadth of the side-chamber, four cubits round about on every side of the house round about.", "darby": "And he measured the wall of the house, six cubits; and the breadth of the side-chambers, four cubits, round about the house on every side.", "twenty": "", "jps": "Then he measured the wall of the house, six cubits; and the breadth of every side-chamber, four cubits, round about the house on every side.", "acv": "Then he measured the wall of the house, six cubits, and the breadth of every side-chamber, four cubits, round about the house on every side.", "anderson": "", "haweis": "", "noyes": "And he measured the wall of the house, six cubits; and the breadth of every side-chamber, four cubits round about, round about the house:", "webster": "Afterward he measured the wall of the house, six cubits; and the breadth of [every] side-chamber, four cubits, round the house on every side.", "vulgate": "et mensus est parietem domus sex cubitorum et latitudinem lateris quattuor cubitorum undique per circuitum domus;", "brenton": "And he measured the wall of the house, six cubits: and the breadth of each side, four cubits round about."}}, {"v": 6, "ref": "41:6", "o": "וְ/הַ/צְּלָעוֹת֩ צֵלָ֨ע אֶל צֵלָ֜ע שָׁל֧וֹשׁ וּ/שְׁלֹשִׁ֣ים פְּעָמִ֗ים וּ֠/בָאוֹת בַּ/קִּ֨יר אֲשֶׁר לַ/בַּ֧יִת לַ/צְּלָע֛וֹת סָבִ֥יב סָבִ֖יב לִ/הְי֣וֹת אֲחוּזִ֑ים וְ/לֹֽא יִהְי֥וּ אֲחוּזִ֖ים בְּ/קִ֥יר הַ/בָּֽיִת", "en": {"kjv": "And the side chambers were three, one over another, and thirty in order; and they entered into the wall which was of the house for the side chambers round about, that they might have hold, but they had not hold in the wall of the house.", "web": "The side rooms were in three stories, one over another, and thirty in order; and they entered into the wall which belonged to the house for the side rooms all around, that they might be supported, and not penetrate the wall of the house.", "bsb": "The side rooms were arranged one above another in three levels of thirty rooms each. There were ledges all around the wall of the temple to serve as supports for the side rooms, so that the supports would not be fastened into the wall of the temple itself.", "asv": "And the side-chambers were in three stories, one over another, and thirty in order; and they entered into the wall which belonged to the house for the side-chambers round about, that they might have hold therein, and not have hold in the wall of the house.", "ylt": "And the side-chambers are side-chamber by side-chamber, three and thirty times; and they are entering into the wall--which the house hath for the side-chambers all round about--to be taken hold of, and they are not taken hold of by the wall of the house.", "dra": "And the side chambers one by another, were twice thirty-three: and they bore outwards, that they might enter in through the wall of the house in the sides round about, to hold in, and not to touch the wall of the temple.", "bbe": "And the side-rooms, room over room, were three times thirty; there were inlets in the wall of the house for the side-rooms round about, for supports in the wall of the house.", "geneva": "And the chambers were chamber vpon chaber, three and thirtie foote high, and they entred into the wall made for the chambers which was round about the house, that the postes might bee fastened therein, and not be fastened in the wall of the house.", "wycliffe": "Forsothe the sidis weren tweies thre and thretti, the side to the side; and tho weren stondynge an hiy, that entriden bi the wal of the hous, in the sidis bi cumpas, that tho helden togidere, and touchiden not the wal of the temple.", "rotherham": "And the side-chambers, one over another were three, and that thirty times, and they entered into the wall which pertained to the house for the side-chambers round about on every side that they might have support, -and yet not have support in the wall of the house itself.", "darby": "And the side-chambers were three, chamber over chamber, and thirty in order; and they entered into the wall which the house had for the side-chambers round about, that they might have hold; but they had not hold in the wall of the house.", "twenty": "", "jps": "And the side-chambers were one over another, three and thirty times; and there were cornices in the wall which belonged to the house for the side-chambers round about, that they might have hold therein, and not have hold in the wall of the house.", "acv": "And the side-chambers were in three stories, one over another, and thirty in order. And they entered into the wall which belonged to the house for the side-chambers round about, that they might be attached to it, and not be attached to the wall of the house.", "anderson": "", "haweis": "", "noyes": "And the side-chambers were chamber to chamber, three and thirty times; and they entered into the wall of the house of the side-chambers round about, and were connected with it; but they were not connected with the wall of the house.", "webster": "And the side-chambers [were] three, one over another, and thirty in order; and they entered into the wall which [was] of the house for the side-chambers around, that they might have hold, but they had not hold in the wall of the house.", "vulgate": "latera autem latus ad latus bis triginta tria et erant eminentia quae ingrederentur per parietem domus in lateribus per circuitum ut continerent et non adtingerent parietem templi;", "brenton": "And the sides were twice ninety, side against side; and there was a space in the wall of the house at the sides round about, that they should be for them that take hold of them to see, that they should not at all touch the walls of the house."}}, {"v": 7, "ref": "41:7", "o": "וְֽ/רָחֲבָ֡ה וְֽ/נָסְבָה֩ לְ/מַ֨עְלָ/ה לְ/מַ֜עְלָ/ה לַ/צְּלָע֗וֹת כִּ֣י מֽוּסַב הַ֠/בַּיִת לְ/מַ֨עְלָ/ה לְ/מַ֜עְלָ/ה סָבִ֤יב סָבִיב֙ לַ/בַּ֔יִת עַל כֵּ֥ן רֹֽחַב לַ/בַּ֖יִת לְ/מָ֑עְלָ/ה וְ/כֵ֧ן הַ/תַּחְתּוֹנָ֛ה יַעֲלֶ֥ה עַל הָ/עֶלְיוֹנָ֖ה לַ/תִּיכוֹנָֽה", "en": {"kjv": "And there was an enlarging, and a winding about still upward to the side chambers: for the winding about of the house went still upward round about the house: therefore the breadth of the house was still upward, and so increased from the lowest chamber to the highest by the midst.", "web": "The side rooms were wider on the higher levels, because the walls were narrower at the higher levels. Therefore the breadth of the house increased upward; and so one went up from the lowest level to the highest through the middle level.", "bsb": "The side rooms surrounding the temple widened at each successive level, because the structure surrounding the temple ascended by stages corresponding to the narrowing of the temple wall as it rose upward. And so a stairway went up from the lowest story to the highest, through the middle one.", "asv": "And the side-chambers were broader as they encompassed the house higher and higher; for the encompassing of the house went higher and higher round about the house: therefore the breadth of the house continued upward; and so one went up from the lowest chamber to the highest by the middle chamber.", "ylt": "And a broad place and a turning place still upwards are to the side-chambers, for the turning round of the house is still upwards all round about the house: therefore the breadth of the house is upwards, and so the lower one goeth up unto the higher by the midst.", "dra": "And there was a broad passage round about, going up by winding stairs, and it led into the upper loft of the temple all round: therefore was the temple broader in the higher parts: and so from the lower parts they went to the higher by the midst.", "bbe": "The side-rooms became wider as they went higher up the house, by the amount of the space let into the wall up round about the house, because of the inlets in the house; and one went up from the lowest floor by steps to the middle, and from the middle to the upper floor.", "geneva": "And it was large and went rounde mounting vpwarde to the chambers: for the staire of the house was mounting vpwarde, rounde about the house: therefore the house was larger vpward: so they went vp from the lowest chamber to the highest by the middes.", "wycliffe": "And a street was in round, and stiede vpward bi a vijs, and bar in to the soler of the temple bi cumpas; therfor the temple was braddere in the hiyere thingis; and so fro the lowere thingis me stiede to the hiyere thingis, and in to the myddis.", "rotherham": "And there was a broadening and a winding about higher and higher to the side-chambers, for the circuit of the house! was higher and higher round about on every side of the house, for this cause was there a broadening of the house upwards,—and from the lower, one ascended to the higher, by that which was in the middle,", "darby": "And for the side-chambers there was an enlarging, and it went round about [the house] increasing upward; for the surrounding of the house increased upward round about the house; therefore the house had width upward, and so ascended [from] the lower [story] to the upper, by the middle one.", "twenty": "", "jps": "And the side-chambers were broader as they wound about higher and higher; for the winding about of the house went higher and higher round about the house; therefore the breadth of the house continued upward; and so one went up from the lowest row to the highest by the middle.", "acv": "And the side-chambers were broader as they circled the house higher and higher, for the circling of the house went higher and higher round about the house. Therefore the breadth of the house continued upward, and so increased from the lowest chamber to the highest by the middle chamber.", "anderson": "", "haweis": "", "noyes": "And, the side-chambers became wider upward, having a winding ascent. For the circuit of the house went still upward, round about the house; therefore the greater breadth of the house was upward; and so they ascended from the lowest story to the highest through the middle story.", "webster": "And [there was] an enlarging, and a winding about still upward to the side-chambers: for the winding about of the house went still upward around the house; therefore the breadth of the house [was still] upward, and so increased [from] the lowest [chamber] to the highest by the midst.", "vulgate": "et platea erat in rotundum ascendens sursum per cocleam et in cenaculum templi deferebat per gyrum idcirco latius erat templum in superioribus et sic de inferioribus ascendebatur ad superiora in medium;", "brenton": "And the breadth of the upper side was made according to the projection out of the wall, against the upper one round about the house, that it might be enlarged above, and that men might go up to the upper chambers from those below, and from the ground-sills to the third story."}}, {"v": 8, "ref": "41:8", "o": "וְ/רָאִ֧יתִי לַ/בַּ֛יִת גֹּ֖בַהּ סָבִ֣יב סָבִ֑יב מיסדות מוּסְד֤וֹת הַ/צְּלָעוֹת֙ מְל֣וֹ הַ/קָּנֶ֔ה שֵׁ֥שׁ אַמּ֖וֹת אַצִּֽילָה", "en": {"kjv": "I saw also the height of the house round about: the foundations of the side chambers were a full reed of six great cubits.", "web": "I saw also that the house had a raised base all around: the foundations of the side rooms were a full reed of six great cubits.", "bsb": "I saw that the temple had a raised base all around it, forming the foundation of the side rooms. It was the full length of a rod, six long cubits.", "asv": "I saw also that the house had a raised basement round about: the foundations of the side-chambers were a full reed of six great cubits.", "ylt": "And I have looked at the house, the height all round about: the foundations of the side-chambers are the fulness of the reed, six cubits by the joining.", "dra": "And I saw in the house the height round about, the foundations of the side chambers which were the measure of a reed the space of six cubits:", "bbe": "And I saw that the house had a stone floor all round; the bases of the side-rooms were a full rod of six great cubits high.", "geneva": "I sawe also the house hie rounde about: the foundations of the chambers were a full reede of fixe great cubites.", "wycliffe": "And Y siy in the hous an hiynesse bi cumpas, the sidis foundid at the mesure of a rehed in the space of sixe cubitis;", "rotherham": "Then saw I that the house had a height round about on every side,—the foundations of the side- chambers, a full reed, six cubits to the joining.", "darby": "And I saw that the house had an elevation round about: the foundations of the side-chambers, a full reed, six cubits to the joint.", "twenty": "", "jps": "I saw also that the house had a raised basement round about; the foundations of the side-chambers were a full reed of six cubits to the joining.", "acv": "I also saw that the house had a raised basement round about. The foundations of the side-chambers were a full reed of six great cubits.", "anderson": "", "haweis": "", "noyes": "I saw also the height of the house round about; the foundations of the side-chambers were a full reed, six cubits to the knuckles.", "webster": "I saw also the hight of the house around: the foundations of the side-chambers [were] a full reed of six great cubits.", "vulgate": "et vidi in domo altitudinem per circuitum fundata latera ad mensuram calami sex cubitorum spatio;", "brenton": "And as for the height of the house round about, each space between the sides was equal to a reed of six cubits;"}}, {"v": 9, "ref": "41:9", "o": "רֹ֣חַב הַ/קִּ֧יר אֲֽשֶׁר לַ/צֵּלָ֛ע אֶל הַ/ח֖וּץ חָמֵ֣שׁ אַמּ֑וֹת וַ/אֲשֶׁ֣ר מֻנָּ֔ח בֵּ֥ית צְלָע֖וֹת אֲשֶׁ֥ר לַ/בָּֽיִת", "en": {"kjv": "The thickness of the wall, which was for the side chamber without, was five cubits: and that which was left was the place of the side chambers that were within.", "web": "The thickness of the wall, which was for the side rooms, on the outside, was five cubits: and that which was left was the place of the side rooms that belonged to the house.", "bsb": "The outer wall of the side rooms was five cubits thick, and the open area between the side rooms of the temple", "asv": "The thickness of the wall, which was for the side-chambers, on the outside, was five cubits: and that which was left was the place of the side-chambers that belonged to the house.", "ylt": "The breadth of the wall that is to the side-chamber at the outside is five cubits; and that which is left is the place of the side-chambers that are to the house.", "dra": "And the thickness of the wall for the side chamber without, which was five cubits: and the inner house was within the side chambers of the house,", "bbe": "The wall supporting the side-rooms on the outside was five cubits thick: and there was a free space of five cubits between the side-rooms of the house.", "geneva": "The thickenesse of the wall which was for the chamber without, was fiue cubites, and that which remained, was the place of the chambers that were within.", "wycliffe": "and the breede by the wal of the side with outforth, of fyue cubitis; and the ynnere hous was in the sidis of the hous.", "rotherham": "The breadth of the wall which pertained to the side-chamber on the outside was five cubits,- and that which was left vacant between the side-chambers which pertained to the house.", "darby": "The thickness of the wall, which was for the side-chambers without, was five cubits, as also what was left free along the building of the side-chambers that pertained to the house.", "twenty": "", "jps": "The breadth of the outer wall which belonged to the side-chambers was five cubits; and so that which was left by the structure of the side-chambers that belonged to the house.", "acv": "The thickness of the wall, which was for the side-chambers, on the outside, was five cubits. And that which was left was the place of the side-chambers that belonged to the house.", "anderson": "", "haweis": "", "noyes": "The thickness of the wall of the side-chambers outward was five cubits, and the space which was left was the place of the side-chambers of the house.", "webster": "The thickness of the wall, which [was] for the side-chamber without, [was] five cubits: and [that] which [was] left [was] the place of the side-chambers that [were] within.", "vulgate": "et latitudinem per parietem lateris forinsecus quinque cubitorum et interior domus in lateribus domus;", "brenton": "and the breadth of the wall of each side without was five cubits; and the spaces that were left between the sides of the house,"}}, {"v": 10, "ref": "41:10", "o": "וּ/בֵ֨ין הַ/לְּשָׁכ֜וֹת רֹ֣חַב עֶשְׂרִ֥ים אַמָּ֛ה סָבִ֥יב לַ/בַּ֖יִת סָבִ֥יב סָבִֽיב", "en": {"kjv": "And between the chambers was the wideness of twenty cubits round about the house on every side.", "web": "Between the rooms was a breadth of twenty cubits around the house on every side.", "bsb": "and the outer chambers was twenty cubits wide all around the temple.", "asv": "And between the chambers was a breadth of twenty cubits round about the house on every side.", "ylt": "And between the chambers is a breadth of twenty cubits round about the house, all round about.", "dra": "And between the chambers was the breadth of twenty cubits round about the house on every side.", "bbe": "And between the rooms was a space twenty cubits wide all round the house.", "geneva": "And betweene the chambers was the widenes of twentie cubites round about the House on euery side.", "wycliffe": "And bitwixe treseries Y siy the breede of twenti cubitis in the cumpas of the hous on ech side;", "rotherham": "And between the chambers, was a breadth of twenty cubits round about the house round about on every side,", "darby": "And between the cells [and the house] was a width of twenty cubits round about the house on every side.", "twenty": "", "jps": "And between the chambers was a breadth of twenty cubits round about the house on every side.", "acv": "And between the chambers was a breadth of twenty cubits round about the house on every side.", "anderson": "", "haweis": "", "noyes": "And between the rooms was the breadth of twenty cubits round about the house on every side.", "webster": "And between the chambers [was] the width of twenty cubits around the house on every side.", "vulgate": "et inter gazofilacia latitudinem viginti cubitorum in circuitu domus undique;", "brenton": "and between the chambers, were a width of twenty cubits, the circumference of the house."}}, {"v": 11, "ref": "41:11", "o": "וּ/פֶ֤תַח הַ/צֵּלָע֙ לַ/מֻּנָּ֔ח פֶּ֤תַח אֶחָד֙ דֶּ֣רֶךְ הַ/צָּפ֔וֹן וּ/פֶ֥תַח אֶחָ֖ד לַ/דָּר֑וֹם וְ/רֹ֨חַב֙ מְק֣וֹם הַ/מֻּנָּ֔ח חָמֵ֥שׁ אַמּ֖וֹת סָבִ֥יב סָבִֽיב", "en": {"kjv": "And the doors of the side chambers were toward the place that was left, one door toward the north, and another door toward the south: and the breadth of the place that was left was five cubits round about.", "web": "The doors of the side rooms were toward an open area that was left, one door toward the north, and another door toward the south. The width of the open area was five cubits all around.", "bsb": "The side rooms opened into this area, with one entrance on the north and another on the south. The open area was five cubits wide all around.", "asv": "And the doors of the side-chambers were toward the place that was left, one door toward the north, and another door toward the south: and the breadth of the place that was left was five cubits round about.", "ylt": "And the opening of the side-chamber is to the place left, one opening northward, and one opening southward, and the breadth of the place that is left is five cubits all round about.", "dra": "And the door of the side chambers was turned towards the place of prayer: one door was toward the north, and another door was toward the south: and the breadth of the place for prayer, was five cubits round about.", "bbe": "And the free space had doors opening from the side-rooms, one door on the north and one door on the south: and the free space was five cubits wide all round.", "geneva": "And the doores of the chambers were toward the place that remained, one doore toward the North, and another doore toward the South, and the breadth of the place that remained, was fiue cubites round about.", "wycliffe": "and Y siy the dore of the side to preier; o dore to the weie of the north, and o dore to the weie of the south; and Y siy the breede of place to preier, of fyue cubitis in cumpas.", "rotherham": "And the entrance of the side-chamber, was at the vacant space, one entrance toward the north, and another entrance, toward the south,—and the breadth of the place left vacant was five cubits round about on every side.", "darby": "And the entry of the side-chambers was toward what was left free, one entry toward the north, and one entry toward the south; and the width of the space left free was five cubits round about.", "twenty": "", "jps": "And the doors of the side-chambers were toward the place that was left, one door toward the north, and another door toward the south; and the breadth of the place that was left was five cubits round about.", "acv": "And the doors of the side-chambers were toward the place that was left, one door toward the north, and another door toward the south. And the breadth of the place that was left was five cubits round about.", "anderson": "", "haweis": "", "noyes": "And the doors of the side-chambers were toward the space that was left, one door toward the north, and another door toward the south; and the breadth of the space that was left was five cubits round about.", "webster": "And the doors of the side-chambers [were] towards [the place that was] left, one door towards the north, and another door towards the south: and the breadth of the place that was left [was] five cubits around.", "vulgate": "et ostium lateris ad orationem ostium unum ad viam aquilonis et ostium unum ad viam australem et latitudinem loci ad orationem quinque cubitorum in circuitu;", "brenton": "And the doors of the chambers were toward the space left by the one door that looked northward, and there was one door southward; and the breadth of the remaining open space was five cubits in extent round about."}}, {"v": 12, "ref": "41:12", "o": "וְ/הַ/בִּנְיָ֡ן אֲשֶׁר֩ אֶל פְּנֵ֨י הַ/גִּזְרָ֜ה פְּאַ֣ת דֶּֽרֶךְ הַ/יָּ֗ם רֹ֚חַב שִׁבְעִ֣ים אַמָּ֔ה וְ/קִ֧יר הַ/בִּנְיָ֛ן חָֽמֵשׁ אַמּ֥וֹת רֹ֖חַב סָבִ֣יב סָבִ֑יב וְ/אָרְכּ֖/וֹ תִּשְׁעִ֥ים אַמָּֽה", "en": {"kjv": "Now the building that was before the separate place at the end toward the west was seventy cubits broad; and the wall of the building was five cubits thick round about, and the length thereof ninety cubits.", "web": "The building that was before the separate place at the side toward the west was seventy cubits broad; and the wall of the building was five cubits thick all around, and its length ninety cubits.", "bsb": "Now the building that faced the temple courtyard on the west was seventy cubits wide, and the wall of the building was five cubits thick all around, with a length of ninety cubits.", "asv": "And the building that was before the separate place at the side toward the west was seventy cubits broad; and the wall of the building was five cubits thick round about, and the length thereof ninety cubits.", "ylt": "As to the building that is at the front of the separate place at the corner westward, the breadth is seventy cubits, and the wall of the building five cubits broad all round about, and its length ninety cubits.", "dra": "And the building that was separate, and turned to the way that looked toward the sea, was seventy cubits broad and the wall of the building, five cubits thick round about: and ninety cubits long.", "bbe": "And the building which was in front of the separate place at the side to the west was seventy cubits wide; the wall of the building was five cubits thick all round and ninety cubits long.", "geneva": "Nowe the building that was before the separate place toward the West corner, was seuentie cubites broad, and the wall of the building was fiue cubites thick, round about, and ye length ninetie cubites.", "wycliffe": "And the bildyng that was ioyned to the place departid, and turned to the weie biholdynge to the see, of the breede of seuenti cubitis; sotheli the wal of the bildyng of fyue cubitis of breede bi cumpas, and the lengthe therof of nynti cubitis.", "rotherham": "And the building which was toward the front of the secluded place on the side toward the west was in breadth seventy cubits, and the wall of the building was five cubits in breadth round about on every side, -and the length thereof ninety cubits.", "darby": "And the building that was before the separate place at the end toward the west was seventy cubits broad; and the wall of the building was five cubits thick round about; and its length ninety cubits.", "twenty": "", "jps": "And the building that was before the separate place at the side toward the west was seventy cubits broad; and the wall of the building was five cubits thick round about, and the length thereof ninety cubits.", "acv": "And the building that was before the separate place at the side toward the west was seventy cubits broad, and the wall of the building was five cubits thick round about, and the length of it ninety cubits.", "anderson": "", "haweis": "", "noyes": "And the building which was before the separate place, at the side toward the west, was seventy cubits broad; and the wall of the building was five cubits thick round about, and the length thereof was ninety cubits.", "webster": "Now the building that was before the separate place at the end towards the west [was] seventy cubits broad; and the wall of the building [was] five cubits thick around, and its length ninety cubits.", "vulgate": "et aedificium quod erat separatum versumque ad viam respicientem ad mare latitudinis septuaginta cubitorum paries autem aedificii quinque cubitorum latitudinis per circuitum et longitudo eius nonaginta cubitorum;", "brenton": "And the partition wall in front of the remaining space, toward the west, was seventy cubits in breadth; the breadth of the partition wall was five cubits round about, and the length of it ninety cubits."}}, {"v": 13, "ref": "41:13", "o": "וּ/מָדַ֣ד אֶת הַ/בַּ֔יִת אֹ֖רֶךְ מֵאָ֣ה אַמָּ֑ה וְ/הַ/גִּזְרָ֤ה וְ/הַ/בִּנְיָה֙ וְ/קִ֣ירוֹתֶ֔י/הָ אֹ֖רֶךְ מֵאָ֥ה אַמָּֽה", "en": {"kjv": "So he measured the house, an hundred cubits long; and the separate place, and the building, with the walls thereof, an hundred cubits long;", "web": "So he measured the house, one hundred cubits long; and the separate place, and the building, with its walls, one hundred cubits long;", "bsb": "Then he measured the temple to be a hundred cubits long, and the temple courtyard and the building with its walls were also a hundred cubits long.", "asv": "So he measured the house, a hundred cubits long; and the separate place, and the building, with the walls thereof, a hundred cubits long;", "ylt": "And he hath measured the house, the length is a hundred cubits; and the separate place, and the building, and its walls, the length is a hundred cubits;", "dra": "And he measured the length of the house, a hundred cubits: and the separate building, and the walls thereof, a hundred cubits in length.", "bbe": "And he took the measure of the house; it was a hundred cubits long; and the separate place and the building with its walls was a hundred cubits long;", "geneva": "So he measured the house an hundreth cubites long, and the separate place and the building with the walles thereof were an hundreth cubites long.", "wycliffe": "And he mat the lengthe of the hous, of an hundrid cubitis; and that that was departid, the bildyng and the wallis therof, of lengthe of an hundrid cubitis.", "rotherham": "And he measured the house, in length, a hundred cubits,—and the secluded place and the structure and the walls thereof, in length, a hundred cubits.", "darby": "And he measured the house: the length a hundred cubits; and the separate place, and the building, and its walls, the length a hundred cubits;", "twenty": "", "jps": "And he measured the house, a hundred cubits long; and the separate place, and the building, with the walls thereof, a hundred cubits long;", "acv": "So he measured the house, a hundred cubits long, and the separate place, and the building, with the walls of it, a hundred cubits long,", "anderson": "", "haweis": "", "noyes": "Then he measured the length of the house, a hundred cubits; and the length of the separate place and the building and the walls thereof, a hundred cubits.", "webster": "So he measured the house, a hundred cubits long; and the separate place, and the building, with its walls, a hundred cubits long;", "vulgate": "et mensus est domus longitudinem centum cubitorum et quod separatum erat aedificium et parietes eius longitudinis centum cubitorum;", "brenton": "And he measured in front of the house a length of a hundred cubits, and the remaining spaces and the partitions; and the walls thereof were in length a hundred cubits."}}, {"v": 14, "ref": "41:14", "o": "וְ/רֹחַב֩ פְּנֵ֨י הַ/בַּ֧יִת וְ/הַ/גִּזְרָ֛ה לַ/קָּדִ֖ים מֵאָ֥ה אַמָּֽה", "en": {"kjv": "Also the breadth of the face of the house, and of the separate place toward the east, an hundred cubits.", "web": "also the breadth of the face of the house, and of the separate place toward the east, one hundred cubits.", "bsb": "The width of the temple courtyard on the east, including the front of the temple, was a hundred cubits.", "asv": "also the breadth of the face of the house, and of the separate place toward the east, a hundred cubits.", "ylt": "and the breadth of the front of the house, and of the separate place eastward, a hundred cubits.", "dra": "And the breadth before the face of the house, and of the separate place toward the east, a hundred cubits.", "bbe": "And the east front of the house and of the separate place was a hundred cubits wide.", "geneva": "Also the breadth of the forefront of the house and of the separate place towarde the East, was an hundreth cubites.", "wycliffe": "Forsothe the breede of the street bifor the face of the hous, and of that that was departid ayens the eest, was of an hundrid cubitis.", "rotherham": "And the breadth of the front of the house and the secluded place toward the east, a hundred cubits.", "darby": "and the breadth of the front of the house, and of the separate places toward the east, a hundred cubits.", "twenty": "", "jps": "also the breadth of the face of the house and of the separate place toward the east, a hundred cubits.", "acv": "also the breadth of the face of the house, and of the separate place toward the east, a hundred cubits.", "anderson": "", "haweis": "", "noyes": "Also the breadth towards the front of the house and of the separate place toward the east was a hundred cubits.", "webster": "Also the breadth of the face of the house, and of the separate place towards the east, a hundred cubits.", "vulgate": "latitudo autem ante faciem domus et eius quod erat separatum contra orientem centum cubitorum;", "brenton": "And the breadth in front of the house, and the remaining spaces before it were a hundred cubits."}}, {"v": 15, "ref": "41:15", "o": "וּ/מָדַ֣ד אֹֽרֶךְ הַ֠/בִּנְיָן אֶל פְּנֵ֨י הַ/גִּזְרָ֜ה אֲשֶׁ֨ר עַל אַחֲרֶ֧י/הָ ו/אתוקי/הא וְ/אַתִּיקֶ֛י/הָא מִ/פּ֥וֹ וּ/מִ/פּ֖וֹ מֵאָ֣ה אַמָּ֑ה וְ/הַֽ/הֵיכָל֙ הַ/פְּנִימִ֔י וְ/אֻֽלַמֵּ֖י הֶ/חָצֵֽר", "en": {"kjv": "And he measured the length of the building over against the separate place which was behind it, and the galleries thereof on the one side and on the other side, an hundred cubits, with the inner temple, and the porches of the court;", "web": "He measured the length of the building before the separate place which was at its back, and its galleries on the one side and on the other side, one hundred cubits; and the inner temple, and the porches of the court;", "bsb": "Next he measured the length of the building facing the temple courtyard at the rear of the temple, including its galleries on each side; it was a hundred cubits. The outer sanctuary, the inner sanctuary, and the porticoes facing the court,", "asv": "And he measured the length of the building before the separate place which was at the back thereof, and the galleries thereof on the one side and on the other side, a hundred cubits; and the inner temple, and the porches of the court;", "ylt": "And he hath measured the length of the building unto the front of the separate place that is at its hinder part, and its galleries on this side and on that side, a hundred cubits, and the inner temple and the porches of the court,", "dra": "And he measured the length of the building over against it, which was separated at the back of it: and the galleries on both sides a hundred cubits: and the inner temple, and the porches of the court.", "bbe": "And he took the measure of the building in front of the separate place which was at the back of it, and the pillared walks on one side and on the other side; they were a hundred cubits long; and the Temple and the inner part and its outer covered way were covered in;", "geneva": "And hee measured the length of the building, ouer against the separate place, which was behinde it, and the chambers on the one side and on the other side an hundreth cubites with the Temple within, and the arches of the court.", "wycliffe": "And he mat the lengthe of the bildyng ayens the face of that, that was departid at the bak; he mat the boteraces on euer either side of an hundrid cubitis. And he mat the ynnere temple, and the porchis of the halle,", "rotherham": "And he measured the length of the building against the front of the secluded place which was over the hinder part thereof and the galleries thereof on this side and on that side a hundred cubits,—with the inner temple and the porches of the court:", "darby": "And he measured the length of the building before the separate place, which was at the back of it, with its galleries on the one side and on the other side, a hundred cubits; and the inner temple, and the porches of the court.", "twenty": "", "jps": "And he measured the length of the building before the separate place which was at the back thereof, and the galleries thereof on the one side and on the other side, a hundred cubits. Now the temple, and the inner place, and the porches of the court,", "acv": "And he measured the length of the building before the separate place which was at the back of it, and the galleries of it on the one side and on the other side, a hundred cubits, and the inner temple, and the porches of the court,", "anderson": "", "haweis": "", "noyes": "And he measured the length of the building before the separate place, and that which was behind it, and the galleries thereof on this side and on that side, a hundred cubits; and the inner temple, and the porches of the court,", "webster": "And he measured the length of the building over against the separate place which [was] behind it, and its galleries on the one side and on the other side, a hundred cubits, with the inner temple, and the porches of the court;", "vulgate": "et mensus est longitudinem aedificii contra faciem eius quod erat separatum ad dorsum ekthetas ex utraque parte centum cubitorum et templum interius et vestibula atrii;", "brenton": "And he measured the length of the partition in front of the space left by the back parts of that house; and the spaces left on this side and on that side were in length a hundred cubits: and the temple and the corners and the outer porch were ceiled."}}, {"v": 16, "ref": "41:16", "o": "הַ/סִּפִּ֡ים וְ/הַ/חַלּוֹנִ֣ים הָ֠/אֲטֻמוֹת וְ/הָ/אַתִּיקִ֤ים סָבִיב֙ לִ/שְׁלָשְׁתָּ֔/ם נֶ֧גֶד הַ/סַּ֛ף שְׂחִ֥יף עֵ֖ץ סָבִ֣יב סָבִ֑יב וְ/הָ/אָ֨רֶץ֙ עַד הַֽ/חַלֹּנ֔וֹת וְ/הַֽ/חַלֹּנ֖וֹת מְכֻסּֽוֹת", "en": {"kjv": "The door posts, and the narrow windows, and the galleries round about on their three stories, over against the door, cieled with wood round about, and from the ground up to the windows, and the windows were covered;", "web": "the thresholds, and the closed windows, and the galleries around on their three stories, over against the threshold, with wood ceilings all around, and from the ground up to the windows, (now the windows were covered),", "bsb": "as well as the thresholds and the beveled windows and the galleries all around with their three levels opposite the threshold, were overlaid with wood on all sides. They were paneled from the ground to the windows, and the windows were covered.", "asv": "the thresholds, and the closed windows, and the galleries round about on their three stories, over against the threshold, ceiled with wood round about, and from the ground up to the windows (now the windows were covered),", "ylt": "the thresholds, and the narrow windows, and the galleries round about them three, over-against the threshold, a ceiling of wood all round about, and the ground unto the windows and the covered windows,", "dra": "The thresholds, and the oblique windows, and the galleries round about on three sides, over against the threshold of every one, and floored with wood all round about: and the ground was up to the windows, and the windows were shut over the doors.", "bbe": "And the sloping windows and the covered ways round all three of them were of shakiph-wood all round from the level of the earth up to the windows;", "geneva": "The postes and the narowe windowes, and the chambers round about, on three sides ouer against the postes, sieled with cedar wood rounde about, and from the ground vp to the windowes, and the windowes were sieled.", "wycliffe": "lyntels, and wyndows narowe withoutforth and broode with ynne; boteraces in cumpas bi thre partis, ayenst the lintel of ech, and araied with tree bi cumpas al aboute; sotheli fro the erthe til to the wyndows, and the wyndows weren closid on the doris,", "rotherham": "the entrance spaces and the latticed windows and the galleries round about their three stories, over against the entrance spaces wainscoted with wood, round about on every side,—and from the ground up to the windows, and the windows, were covered;", "darby": "The thresholds, and the closed windows, and the galleries round about the three of them (opposite the thresholds it was wainscoted with wood round about, and from the ground up to the windows, and the windows were covered),", "twenty": "", "jps": "the jambs, and the narrow windows, and the galleries, that they three had round about, over against the jambs there was a veneering of wood round about, and from the ground up to the windows; and the windows were covered;", "acv": "the thresholds, and the closed windows, and the galleries round about on their three stories, opposite the threshold, paneled with wood round about, and from the ground up to the windows, (now the windows were covered),", "anderson": "", "haweis": "", "noyes": "the thresholds, and the windows that were closed, and the galleries round about the three sides. Over against the threshold was a table of wood round about, from the ground to the windows, and the windows were covered with it;", "webster": "The door posts, and the narrow windows, and the galleries around on their three stories, over against the door, ceiled with wood around, and from the ground up to the windows, and the windows [were] covered;", "vulgate": "limina et fenestras obliquas et ekthetas in circuitu per tres partes contra uniuscuiusque limen stratumque ligno per gyrum in circuitu terra autem usque ad fenestras et fenestrae clausae super ostia;", "brenton": "And the windows were latticed, giving light round about to the three stories, so as to look through: and the house and the parts adjoining were planked round about, and so was the floor, and from the floor up to the windows, and the window shutters folded back in three parts for one to look through."}}, {"v": 17, "ref": "41:17", "o": "עַל מֵ/עַ֣ל הַ/פֶּ֡תַח וְ/עַד הַ/בַּיִת֩ הַ/פְּנִימִ֨י וְ/לַ/ח֜וּץ וְ/אֶל כָּל הַ/קִּ֨יר סָבִ֧יב סָבִ֛יב בַּ/פְּנִימִ֥י וּ/בַ/חִיצ֖וֹן מִדּֽוֹת", "en": {"kjv": "To that above the door, even unto the inner house, and without, and by all the wall round about within and without, by measure.", "web": "to the space above the door, even to the inner house, and outside, and by all the wall all around inside and outside, by measure.", "bsb": "In the space above the outside of the entrance to the inner sanctuary on all the walls, spaced evenly around the inner and outer sanctuary,", "asv": "to the space above the door, even unto the inner house, and without, and by all the wall round about within and without, by measure.", "ylt": "over above the opening, and unto the inner-house, and at the outside, and by all the wall all round about within and without by measure.", "dra": "And even to the inner house, and without all the wall round about within and without, by measure.", "bbe": "And there was a roof over the doorway and as far as the inner house, and to the outside and on the wall all round, inside and outside.", "geneva": "And from aboue the doore vnto the inner house and without, and by all the wall rounde about within and without it was sieled according to the measure.", "wycliffe": "and til to the ynnere hous, and withoutforth bi al the wal in cumpas, with ynne and with outforth at mesure.", "rotherham": "unto the space above the entrance even unto the inner house and without and against all the wall round about on every side within and without, were the measures", "darby": "[and] above, over the entry, even unto the inner house, and without, and by all the wall round about, within and without, [all was] by measure.", "twenty": "", "jps": "to the space above the door, even unto the inner house, and without, and on all the wall round about within and without, by measure.", "acv": "to the space above the door, even to the inner house, and outside, and by all the wall round about inside and outside, by measure.", "anderson": "", "haweis": "", "noyes": "upon the space above every door, and upon the inner house, and without, and upon all the wall round about within and without, according to measure.", "webster": "To that above the door, even to the inner house, and without, and by all the wall around within and without, by measure.", "vulgate": "et usque ad domum interiorem et forinsecus per omnem parietem in circuitu intrinsecus et forinsecus ad mensuram;", "brenton": "And almost all the way to the inner, and close to the outer side, and upon all the wall round about within and without,"}}, {"v": 18, "ref": "41:18", "o": "וְ/עָשׂ֥וּי כְּרוּבִ֖ים וְ/תִֽמֹרִ֑ים וְ/תִֽמֹרָה֙ בֵּין כְּר֣וּב לִ/כְר֔וּב וּ/שְׁנַ֥יִם פָּנִ֖ים לַ/כְּרֽוּב", "en": {"kjv": "And it was made with cherubims and palm trees, so that a palm tree was between a cherub and a cherub; and every cherub had two faces;", "web": "It was made with cherubim and palm trees; and a palm tree was between cherub and cherub, and every cherub had two faces;", "bsb": "were alternating carved cherubim and palm trees. Each cherub had two faces:", "asv": "And it was made with cherubim and palm-trees; and a palm-tree was between cherub and cherub, and every cherub had two faces;", "ylt": "And it is made with cherubs and palm-trees, and a palm-tree is between cherub and cherub, and two faces are to the cherub;", "dra": "And there were cherubims and palm trees wrought, so that a palm tree was between a cherub and a cherub, and every cherub had two faces.", "bbe": "And it had pictured forms of winged beings and palm-trees; a palm-tree between two winged ones, and every winged one had two faces;", "geneva": "And it was made with Cherubims and palme trees, so that a palme tree was betweene a Cherub and a Cherub: and euery Cherub had two faces.", "wycliffe": "And cherubyns and palm trees weren maad craftili, and a palm tree bitwixe cherub and cherub; and cherub hadde twei faces,", "rotherham": "And it was made with cherubim and palm-trees,—with a palm-tree between cherub and cherub, and two faces had each cherub;", "darby": "And it was made with cherubim and palm-trees, and a palm-tree was between cherub and cherub; and the cherub had two faces:", "twenty": "", "jps": "And it was made with cherubim and palm-trees; and a palm-tree was between cherub and cherub, and every cherub had two faces;", "acv": "And it was made with cherubim and palm trees, and a palm tree was between cherub and cherub. And every cherub had two faces,", "anderson": "", "haweis": "", "noyes": "And cherubs and palm-trees were made, one palm-tree between two cherubs, and every cherub had two faces;", "webster": "And [it was] made with cherubim and palm-trees, so that a palm-tree [was] between a cherub and a cherub; and [every] cherub had two faces;", "vulgate": "et fabrefacta cherubin et palmae et palma inter cherub et cherub duasque facies habebat cherub;", "brenton": "were carved cherubs and palm-trees between the cherubs, and each cherub had two faces."}}, {"v": 19, "ref": "41:19", "o": "וּ/פְנֵ֨י אָדָ֤ם אֶל הַ/תִּֽמֹרָה֙ מִ/פּ֔וֹ וּ/פְנֵֽי כְפִ֥יר אֶל הַ/תִּֽמֹרָ֖ה מִ/פּ֑וֹ עָשׂ֥וּי אֶל כָּל הַ/בַּ֖יִת סָבִ֥יב סָבִֽיב", "en": {"kjv": "So that the face of a man was toward the palm tree on the one side, and the face of a young lion toward the palm tree on the other side: it was made through all the house round about.", "web": "so that there was the face of a man toward the palm tree on the one side, and the face of a young lion toward the palm tree on the other side. It was made like this through all the house all around:", "bsb": "the face of a man was toward the palm tree on one side, and the face of a young lion was toward the palm tree on the other side. They were carved all the way around the temple.", "asv": "so that there was the face of a man toward the palm-tree on the one side, and the face of a young lion toward the palm-tree on the other side. Thus was it made through all the house round about:", "ylt": "and the face of man is unto the palm-tree on this side, and the face of a young lion unto the palm-tree on that side; it is made unto all the house all round about.", "dra": "The face of a man was toward the palm tree on one side, and the face of a lion was toward the palm tree on the other side: set forth through all the house round about.", "bbe": "So that there was the face of a man turned to the palm-tree on one side, and the face of a young lion on the other side: so it was made all round the house.", "geneva": "So that the face of a man was towarde the palme tree on the one side, and the face of a lyon toward the palme tree on the other side: thus was it made through all the house round about.", "wycliffe": "the face of a man bisidis the palm tree on this side, and the face of a lioun expressid bisidis the palm tree on `the tother side. Bi al the hous in cumpas, fro the erthe til to the hiyere part,", "rotherham": "and, the face of a man, was toward the palm-tree on this side, and, the face of a young lion, was toward the palm-tree on that side,—[thus was it] made unto all the house, round about on every side.", "darby": "the face of a man was toward the palm-tree on the one side, and the face of a young lion toward the palm-tree on the other side: [so] was it made upon all the house round about.", "twenty": "", "jps": "so that there was the face of a man toward the palm-tree on the one side, and the face of a young lion toward the palm-tree on the other side; thus was it made through all the house round about.", "acv": "so that there was the face of a man toward the palm tree on the one side, and the face of a young lion toward the palm tree on the other side, made through all the house round about.", "anderson": "", "haweis": "", "noyes": "and the face of a man was toward a palm-tree on one side, and the face of a lion toward a palm-tree on the other side. So was it made upon all the house round about.", "webster": "So that the face of a man [was] towards the palm-tree on the one side, and the face of a young lion towards the palm-tree on the other side: [it was] made through all the house around.", "vulgate": "faciem hominis iuxta palmam ex hac parte et faciem leonis iuxta palmam ex alia parte expressam per omnem domum in circuitu;", "brenton": "The face of a man was toward one palm-tree on this side and on that side, and the face of a lion toward another palm-tree on this side and on that side: the house was carved all round."}}, {"v": 20, "ref": "41:20", "o": "מֵ/הָ/אָ֨רֶץ֙ עַד מֵ/עַ֣ל הַ/פֶּ֔תַח הַ/כְּרוּבִ֥ים וְ/הַ/תִּֽמֹרִ֖ים עֲשׂוּיִ֑ם וְ/קִ֖יר הַׄ/הֵׄיׄכָֽׄלׄ", "en": {"kjv": "From the ground unto above the door were cherubims and palm trees made, and on the wall of the temple.", "web": "from the ground to above the door were cherubim and palm trees made: thus was the wall of the temple.", "bsb": "Cherubim and palm trees were carved on the wall of the outer sanctuary from the floor to the space above the entrance.", "asv": "from the ground unto above the door were cherubim and palm-trees made; thus was the wall of the temple.", "ylt": "from the earth unto above the opening are the cherubs and the palm-trees made, and on the wall of the temple.", "dra": "From the ground even to the upper parts of the gate, were cherubims and palm trees wrought in the wall of the temple.", "bbe": "From earth level up to the windows there were winged ones and palm-trees pictured on the wall.", "geneva": "From the grounde vnto aboue the doore were Cherubims and palme trees made as in the wall of the Temple.", "wycliffe": "cherubyns and palm trees weren grauun in the wal of the temple.", "rotherham": "From the ground as far as the space above the entrance: were the cherubim and the palm-trees made.", "darby": "From the ground unto above the entry were the cherubim and the palm-trees made, and [on] the wall of the temple.", "twenty": "", "jps": "From the ground unto above the door were cherubim and palm-trees made; and so on the wall of the temple.", "acv": "Cherubim and palm trees were made from the ground to above the door. Thus was the wall of the temple.", "anderson": "", "haweis": "", "noyes": "From the ground to above the door were cherubs and palm-trees made, and on the wall of the temple.", "webster": "From the ground to above the door [were] cherubim and palm-trees made, and [on] the wall of the temple.", "vulgate": "de terra usque ad superiora portae cherubin et palmae celatae erant in pariete templi;", "brenton": "From the floor to the ceiling were cherubs and palm-trees carved."}}, {"v": 21, "ref": "41:21", "o": "הַֽ/הֵיכָ֖ל מְזוּזַ֣ת רְבֻעָ֑ה וּ/פְנֵ֣י הַ/קֹּ֔דֶשׁ הַ/מַּרְאֶ֖ה כַּ/מַּרְאֶֽה", "en": {"kjv": "The posts of the temple were squared, and the face of the sanctuary; the appearance of the one as the appearance of the other.", "web": "As for the temple, the door posts were squared; and as for the face of the sanctuary, its appearance was as the appearance of the temple.", "bsb": "The outer sanctuary had a rectangular doorframe, and the doorframe of the sanctuary was similar.", "asv": "As for the temple, the door-posts were squared; and as for the face of the sanctuary, the appearance thereof was as the appearance of the temple.", "ylt": "Of the temple the side post is square, and of the front of the sanctuary, the appearance is as the appearance.", "dra": "The threshold was foursquare, and the face of the sanctuary sight to sight.", "bbe": "...", "geneva": "The postes of the Temple were squared, and thus to looke vnto was the similitude and forme of the Sanctuarie.", "wycliffe": "A threisfold foure cornerid; and the face of the biholdyng of the seyntuarie was ayens the biholding of the auter of tree;", "rotherham": "As for the wall of the temple, the door-posts were squared,—and as for the face of the holy place, the appearance was like the appearance [of the temple] .", "darby": "As for the temple, the door-posts were squared; and the front of the sanctuary had the same appearance.", "twenty": "", "jps": "As for the temple, the jambs were squared; and the face of the sanctuary had an appearance such as is the appearance.", "acv": "As for the temple, the door-posts were squared. And as for the face of the sanctuary, the appearance was as the appearance of the temple.", "anderson": "", "haweis": "", "noyes": "The posts of the temple were four-square; and the front of the sanctuary had the same appearance.", "webster": "The posts of the temple [were] squared, [and] the face of the sanctuary; the appearance [of the one] as the appearance [of the other].", "vulgate": "limen quadrangulum et facies sanctuarii aspectus contra aspectum;", "brenton": "And the holy place and the temple opened on four sides; in front of the holy places the appearance was as the look of"}}, {"v": 22, "ref": "41:22", "o": "הַ/מִּזְבֵּ֡חַ עֵ֣ץ שָׁלוֹשׁ֩ אַמּ֨וֹת גָּבֹ֜הַּ וְ/אָרְכּ֣/וֹ שְׁתַּֽיִם אַמּ֗וֹת וּ/מִקְצֹֽעוֹתָי/ו֙ ל֔/וֹ וְ/אָרְכּ֥/וֹ וְ/קִֽירֹתָ֖י/ו עֵ֑ץ וַ/יְדַבֵּ֣ר אֵלַ֔/י זֶ֚ה הַ/שֻּׁלְחָ֔ן אֲשֶׁ֖ר לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "The altar of wood was three cubits high, and the length thereof two cubits; and the corners thereof, and the length thereof, and the walls thereof, were of wood: and he said unto me, This is the table that is before the Lord.", "web": "The altar was of wood, three cubits high, and its length two cubits; and its corners, and its length, and its walls, were of wood: and he said to me, This is the table that is before Yahweh.", "bsb": "There was an altar of wood three cubits high and two cubits square. Its corners, base, and sides were of wood. And the man told me, “This is the table that is before the LORD.”", "asv": "The altar was of wood, three cubits high, and the length thereof two cubits; and the corners thereof, and the length thereof, and the walls thereof, were of wood: and he said unto me, This is the table that is before Jehovah.", "ylt": "Of the altar, the wood is three cubits in height, and its length two cubits; and its corners are to it, and its length, and its walls are of wood, and he speaketh unto me, `This is the table that is before Jehovah.'", "dra": "The altar of wood was three cubits high: and the length thereof was two cubits: and the corners thereof, aid the length thereof, and the walls thereof, were of wood. And he said to me: This is the table before the Lord.", "bbe": "The altar was made of wood, and was three cubits high and two cubits long; it had angles, and its base and sides were of wood; and he said to me, This is the table which is before the Lord.", "geneva": "The altar of wood was three cubites hie, and the length thereof two cubites, and the corners thereof and the length thereof and the sides thereof were of wood. And he sayd vnto me, This is the table that shalbe before the Lord.", "wycliffe": "the heiythe therof was of thre cubitis, and the lengthe therof of twei cubitis; and the corneris therof, and the lengthe therof, and the wallis therof, weren of tree. And he spak to me, This is the boord bifor the Lord.", "rotherham": "The altar, was of wood, three cubits in height and the length thereof, two cubits and the corners thereof and the length thereof and the walls thereof were of wood,—then spake he unto me saying, This, is the table, which is before Yahweh.", "darby": "The altar was of wood, three cubits high, and its length two cubits; and its corners, and its length, and its walls were of wood. And he said unto me, This is the table which is before Jehovah.", "twenty": "", "jps": "The altar, three cubits high, and the length thereof two cubits, was of wood, and so the corners thereof; the length thereof, and the walls thereof, were also of wood; and he said unto me: 'This is the table that is before HaShem.'", "acv": "The altar was of wood, three cubits high, and the length of it two cubits, and the corners of it, and the length of it, and the walls of it, were of wood. And he said to me, This is the table that is before Jehovah.", "anderson": "", "haweis": "", "noyes": "The altar was of wood, three cubits high, and two cubits long; and the corners thereof and the base thereof and the walls thereof were of wood. And he said to me, This is the table that standeth before Jehovah.", "webster": "The altar of wood [was] three cubits high, and its length two cubits; and its corners, and its length, and its walls, [were] of wood: and he said to me, This [is] the table that [is] before the LORD.", "vulgate": "altaris lignei trium cubitorum altitudo et longitudo eius duo cubitorum et anguli eius et longitudo eius et parietes eius lignei et locutus est ad me haec est mensa coram Domino;", "brenton": "a wooden altar, the height of it three cubits, and the length two cubits, and the breadth two cubits; and it had horns, and the base of it and the sides of it were of wood: and he said to me, This is the table, which is before the face of the Lord."}}, {"v": 23, "ref": "41:23", "o": "וּ/שְׁתַּ֧יִם דְּלָת֛וֹת לַֽ/הֵיכָ֖ל וְ/לַ/קֹּֽדֶשׁ", "en": {"kjv": "And the temple and the sanctuary had two doors.", "web": "The temple and the sanctuary had two doors.", "bsb": "Both the outer sanctuary and the inner sanctuary had double doors,", "asv": "And the temple and the sanctuary had two doors.", "ylt": "And two doors are to the temple and to the sanctuary;", "dra": "And there were two doors in the temple, and in the sanctuary.", "bbe": "The Temple had two doors.", "geneva": "And the Temple and the Sanctuarie had two doores.", "wycliffe": "And twei doris weren in the temple, and in the seyntuarie.", "rotherham": "And there were two doors, to the temple, and to the holy place;", "darby": "And the temple and the sanctuary had two doors.", "twenty": "", "jps": "And the temple and the sanctuary had two doors.", "acv": "And the temple and the sanctuary had two doors.", "anderson": "", "haweis": "", "noyes": "And the temple and the sanctuary had two doors.", "webster": "And the temple and the sanctuary had two doors.", "vulgate": "et duo ostia erant in templo et in sanctuario;", "brenton": "And the temple had two doors, and the sanctuary had two doors, with two turning leaves apiece;"}}, {"v": 24, "ref": "41:24", "o": "וּ/שְׁתַּ֥יִם דְּלָת֖וֹת לַ/דְּלָת֑וֹת שְׁ֚תַּיִם מוּסַבּ֣וֹת דְּלָת֔וֹת שְׁ֚תַּיִם לְ/דֶ֣לֶת אֶחָ֔ת וּ/שְׁתֵּ֥י דְלָת֖וֹת לָ/אַחֶֽרֶת", "en": {"kjv": "And the doors had two leaves apiece, two turning leaves; two leaves for the one door, and two leaves for the other door.", "web": "The doors had two leaves each, two turning leaves: two for the one door, and two leaves for the other.", "bsb": "and each door had two swinging panels. There were two panels for one door and two for the other.", "asv": "And the doors had two leaves apiece, two turning leaves: two leaves for the one door, and two leaves for the other.", "ylt": "and two leaves are to the doors, two turning leaves are to the doors, two to the one door, and two leaves to the other.", "dra": "And in the two doors on both sides were two little doors, which were folded within each other: for there were two wickets on both sides of the doors.", "bbe": "And the holy place had two doors, and the doors had two turning leaves, two for one and two for the other.", "geneva": "And the doores had two wickets, euen two turning wickets, two wickets for one doore, and two wickets for another doore.", "wycliffe": "And in the twei doris on euer either side weren twei litle doris, that weren foldun togidere in hem silf; for whi twei doris weren on euer either side of the doris.", "rotherham": "and two leaves to the doors,—two folding leaves, two to the one door and two to the other door.", "darby": "And the doors had two leaves, two turning-leaves: two for the one door, and two leaves for the other.", "twenty": "", "jps": "And the doors had two leaves apiece, two turning leaves; two leaves for the one door, and two leaves for the other.", "acv": "And the doors had two leaves apiece, two turning leaves, two for the one door, and two leaves for the other.", "anderson": "", "haweis": "", "noyes": "And the two doors had two leaves apiece, two turning leaves; two leaves for one door, and two leaves for the other door.", "webster": "And the doors had two leaves each, two turning leaves; two [leaves] for the one door, and two leaves for the other [door].", "vulgate": "et in duobus ostiis ex utraque parte bina erant ostiola quae in se invicem plicabantur bina enim ostia erant ex utraque parte ostiorum;", "brenton": "two leaves to the one, and two leaves to the other door."}}, {"v": 25, "ref": "41:25", "o": "וַ/עֲשׂוּיָ֨ה אֲלֵי/הֶ֜ן אֶל דַּלְת֤וֹת הַֽ/הֵיכָל֙ כְּרוּבִ֣ים וְ/תִֽמֹרִ֔ים כַּ/אֲשֶׁ֥ר עֲשׂוּיִ֖ם לַ/קִּיר֑וֹת וְ/עָ֥ב עֵ֛ץ אֶל פְּנֵ֥י הָ/אוּלָ֖ם מֵ/הַ/חֽוּץ", "en": {"kjv": "And there were made on them, on the doors of the temple, cherubims and palm trees, like as were made upon the walls; and there were thick planks upon the face of the porch without.", "web": "There were made on them, on the doors of the temple, cherubim and palm trees, like as were made on the walls; and there was a threshold of wood on the face of the porch outside.", "bsb": "Cherubim and palm trees like those on the walls were carved on the doors of the outer sanctuary, and there was a wooden canopy outside, on the front of the portico.", "asv": "And there were made on them, on the doors of the temple, cherubim and palm-trees, like as were made upon the walls; and there was a threshold of wood upon the face of the porch without.", "ylt": "And made on them, on the doors of the temple, are cherubs and palm-trees as are made on the walls, and a thickness of wood is at the front of the porch on the outside.", "dra": "And there were cherubims also wrought in the doors of the temple, and the figures of palm trees, like as were made on the walls: for which cause also the planks were thicker in the front of the porch without.", "bbe": "And on them were pictured winged ones and palm-trees, as on the walls; and a ... of wood was on the front of the covered way outside.", "geneva": "And vpon the doores of the Temple there were made Cherubims and palmetrees, like as was made vpon the walles, and there were thicke plankes vpon the forefront of the porch without.", "wycliffe": "And cherubyns and the grauyng of palm trees weren grauun in tho doris of the temple, as also tho weren expressid in the wallis. Wherfor and grettere trees weren in the frount of the porche with outforth,", "rotherham": "And there had been made unto them unto the doors of the temple cherubim and palm-trees, like as had been made to the walls,—and thick beams of wood unto the front of the porch without.", "darby": "And there were made on them, on the doors of the temple, cherubim and palm-trees, as there were made upon the walls; and there was a wooden portal in front of the porch without,", "twenty": "", "jps": "And there were made on them, on the doors of the temple, cherubim and palm-trees, like as were made upon the walls; and there were thick beams of wood upon the face of the porch without.", "acv": "And there were made on them, on the doors of the temple, cherubim and palm trees, just as were made upon the walls. And there was a threshold of wood upon the face of the porch outside.", "anderson": "", "haweis": "", "noyes": "And there were made on them, even on the doors of the temple, cherubs and palm-trees, such as were made upon the walls, and a wooden threshold was before the porch without.", "webster": "And [there were] made on them, on the doors of the temple, cherubim and palm-trees, as [were] made upon the walls; and [there were] thick planks upon the face of the porch without.", "vulgate": "et celata erant in ipsis ostiis templi cherubin et scalptura palmarum sicut in parietibus quoque expressa erat quam ob rem erant et grossiora ligna in vestibuli fronte forinsecus;", "brenton": "And there was carved work upon them, and cherubs on the doors of the temple, and palm-trees according to the carving of the sanctuary; and there were stout planks in front of the porch without."}}, {"v": 26, "ref": "41:26", "o": "וְ/חַלּוֹנִ֨ים אֲטֻמ֤וֹת וְ/תִֽמֹרִים֙ מִ/פּ֣וֹ וּ/מִ/פּ֔וֹ אֶל כִּתְפ֖וֹת הָֽ/אוּלָ֑ם וְ/צַלְע֥וֹת הַ/בַּ֖יִת וְ/הָ/עֻבִּֽים", "en": {"kjv": "And there were narrow windows and palm trees on the one side and on the other side, on the sides of the porch, and upon the side chambers of the house, and thick planks.", "web": "There were closed windows and palm trees on the one side and on the other side, on the sides of the porch: thus were the side rooms of the house, and the thresholds.", "bsb": "There were beveled windows and palm trees on the sidewalls of the portico. The side rooms of the temple also had canopies.", "asv": "And there were closed windows and palm-trees on the one side and on the other side, on the sides of the porch: thus were the side-chambers of the house, and the thresholds.", "ylt": "And narrow windows and palm-trees are on this side, and on that side, at the sides of the porch, and the side-chambers of the house, and the thick places.", "dra": "Upon which were the oblique windows, and the representation of palm trees on this side, and on that side in the sides of the porch, according to the sides of the house, and the breadth of the walls.", "bbe": "And there were sloping windows and palm-trees on one side and on the other, on the sides of the covered way: and the side-rooms of the house and the ...", "geneva": "And there were narow windowes and palme trees on the one side, and on the other side, by the sides of the porch, and vpon ye sides of the house, and thicke plankes.", "wycliffe": "on whiche the wyndows narowe with out and large with ynne, and the licnesse of palm trees weren on this side and on that syde; in the litle vndursettyngis of the porche, bi the sidis of the hous, and bi the breede of the wallis.", "rotherham": "And there were latticed windows and palm-trees on this side and on that side, unto the sides of the porch,—and unto the side chambers of the house and the thick beams.", "darby": "and closed windows and palm-trees on the one side and on the other side, on the sides of the porch and the side chambers of the house and the portals.", "twenty": "", "jps": "And there were narrow windows and palm-trees on the one side and on the other side, on the sides of the porch; there were also the brackets of the house, and the thick beams.", "acv": "And there were closed windows and palm trees on the one side and on the other side, on the sides of the porch. Thus were the side-chambers of the house, and the thresholds.", "anderson": "", "haweis": "", "noyes": "And at the closed windows were palm-trees on this side, and on that side, on the sides of the porch, and on the side-chambers of the house, and on the thresholds.", "webster": "And [there were] narrow windows and palm-trees on the one side and on the other side, on the sides of the porch, and [upon] the side-chambers of the house, and thick planks.", "vulgate": "super quae fenestrae obliquae et similitudo palmarum hinc atque inde in umerulis vestibuli secundum latera domus latitudinemque parietum;", "brenton": "And there were secret windows; and he measured from side to side, to the roofing of the porch; and the sides of the house were closely planked."}}]}, {"c": 42, "verses": [{"v": 1, "ref": "42:1", "o": "וַ/יּוֹצִאֵ֗/נִי אֶל הֶֽ/חָצֵר֙ הַ/חִ֣יצוֹנָ֔ה הַ/דֶּ֖רֶךְ דֶּ֣רֶךְ הַ/צָּפ֑וֹן וַ/יְבִאֵ֣/נִי אֶל הַ/לִּשְׁכָּ֗ה אֲשֶׁ֨ר נֶ֧גֶד הַ/גִּזְרָ֛ה וַ/אֲשֶֽׁר נֶ֥גֶד הַ/בִּנְיָ֖ן אֶל הַ/צָּפֽוֹן", "en": {"kjv": "Then he brought me forth into the utter court, the way toward the north: and he brought me into the chamber that was over against the separate place, and which was before the building toward the north.", "web": "Then he brought me out into the outer court, the way toward the north: and he brought me into the room that was over against the separate place, and which was over against the building toward the north.", "bsb": "Then the man led me out northward into the outer court, and he brought me to the group of chambers opposite the temple courtyard and the outer wall on the north side.", "asv": "Then he brought me forth into the outer court, the way toward the north: and he brought me into the chamber that was over against the separate place, and which was over against the building toward the north.", "ylt": "And he bringeth me forth unto the outer court, the way northward, and he bringeth me in unto the chamber that is over-against the separate place, and that is over-against the building at the north.", "dra": "And he brought me forth into the outward court by the way that leadeth to the north, and he brought me into the chamber that was over against the separate building, and over against the house toward the north.", "bbe": "And he took me out into the inner square in the direction of the north: and he took me into the rooms which were opposite the separate place and opposite the building to the north.", "geneva": "Then brought hee me into the vtter court by the way towarde the North, and he brought me into the chamber that was ouer against the separate place, and which was before the building toward the North.", "wycliffe": "And he ledde me out in to the outermere halle, bi the weie ledynge to the north; and he ledde me in to the treserie, that was ayens the bildyng departid, and ayens the hous goynge to the north;", "rotherham": "Then he took me forth unto the outer court, the way toward the north,—and brought me unto the chamber which was over against the secluded place and which was over against the enclosing-wall, towards the north.", "darby": "And he brought me forth into the outer court, the way toward the north; and he brought me to the cells that were over against the separate place and which were over against the building, toward the north,", "twenty": "", "jps": "Then he brought me forth into the outer court, the way toward the north; and he brought me into the chamber that was over against the separate place, and which was over against the building, toward the north,", "acv": "Then he brought me forth into the outer court, the way toward the north. And he brought me into the chamber that was opposite the separate place, and which was opposite the building toward the north.", "anderson": "", "haweis": "", "noyes": "Then he led me forth to the outer court, in the direction toward the north, and he brought me to the rooms which were before the separate place, and before the building toward the north.", "webster": "Then he brought me forth into the outer court, the way towards the north: and he brought me into the chamber that [was] over against the separate place, and which [was] before the building towards the north.", "vulgate": "et eduxit me in atrium exterius per viam ducentem ad aquilonem et eduxit me in gazofilacium quod erat contra separatum aedificium et contra aedem vergentem ad aquilonem;", "brenton": "And he brought me into the inner court eastward, opposite the northern gate: and he brought me in, and behold five chambers near the vacant space, and near the northern partition,"}}, {"v": 2, "ref": "42:2", "o": "אֶל פְּנֵי אֹ֨רֶךְ֙ אַמּ֣וֹת הַ/מֵּאָ֔ה פֶּ֖תַח הַ/צָּפ֑וֹן וְ/הָ/רֹ֖חַב חֲמִשִּׁ֥ים אַמּֽוֹת", "en": {"kjv": "Before the length of an hundred cubits was the north door, and the breadth was fifty cubits.", "web": "Before the length of one hundred cubits was the north door, and the breadth was fifty cubits.", "bsb": "The building with the door facing north was a hundred cubits long and fifty cubits wide.", "asv": "Before the length of a hundred cubits was the north door, and the breadth was fifty cubits.", "ylt": "At the front of the length is a hundred cubits at the north opening, and the breadth fifty cubits.", "dra": "In the face of the north door was the length of hundred cubits, and the breadth of fifty cubits.", "bbe": "On the north side it was a hundred cubits long and fifty cubits wide,", "geneva": "Before ye length of an hundreth cubites, was the North doore, and it was fiftie cubites broad.", "wycliffe": "in the face an hundrid cubitis of lengthe of the dore of the north, and fifti cubitis of breede,", "rotherham": "Facing the length of the hundred cubits, was the entrance of the north,—and the breadth was fifty cubits:", "darby": "before the length of the hundred cubits: the entry was on the north, and the breadth was fifty cubits,", "twenty": "", "jps": "even to the front of the length of a hundred cubits, with the door on the north, and the breadth of fifty cubits,", "acv": "In front was the north door, the length of a hundred cubits, and the breadth was fifty cubits.", "anderson": "", "haweis": "", "noyes": "The length was a hundred cubits before the gate toward the north, and the breadth was fifty cubits;", "webster": "Before the length of a hundred cubits [was] the north door, and the breadth [was] fifty cubits.", "vulgate": "in facie longitudinis centum cubitos ostii aquilonis et latitudinis quinquaginta cubitos;", "brenton": "a hundred cubits in length toward the north, and in breadth fifty,"}}, {"v": 3, "ref": "42:3", "o": "נֶ֣גֶד הָֽ/עֶשְׂרִ֗ים אֲשֶׁר֙ לֶ/חָצֵ֣ר הַ/פְּנִימִ֔י וְ/נֶ֣גֶד רִֽצְפָ֔ה אֲשֶׁ֖ר לֶ/חָצֵ֣ר הַ/חִֽיצוֹנָ֑ה אַתִּ֥יק אֶל פְּנֵֽי אַתִּ֖יק בַּ/שְּׁלִשִֽׁים", "en": {"kjv": "Over against the twenty cubits which were for the inner court, and over against the pavement which was for the utter court, was gallery against gallery in three stories.", "web": "Over against the twenty cubits which belonged to the inner court, and over against the pavement which belonged to the outer court, was gallery against gallery in the third story.", "bsb": "Gallery faced gallery in three levels opposite the twenty cubits that belonged to the inner court and opposite the pavement that belonged to the outer court.", "asv": "Over against the twentycubitswhich belonged to the inner court, and over against the pavement which belonged to the outer court, was gallery against gallery in the third story.", "ylt": "Over-against the twenty cubits that are to the inner court, and over-against the pavement that is to the outer court, is gallery over-against gallery, in the three storeys .", "dra": "Over against the twenty cubits of the inner court, and over against the pavement of the outward court that was paved with stone, where there was a gallery joined to a triple gallery.", "bbe": "Opposite the space of twenty cubits which was part of the inner square, and opposite the stone floor of the outer square. There were covered ways facing one another on the third floor.", "geneva": "Ouer against the twentie cubites which were for the inner court, and ouer against the pauement, which was for the vtter court, was chamber against chamber in three rowes.", "wycliffe": "ayens twenti cubitis of the ynnere halle, and ayens the pawment araied with stoon of the outermere halle, where a porche was ioyned to thre fold porche.", "rotherham": "over against the twenty which pertained to the inner court, and over against the pavement which pertained to the outer court, was gallery facing gallery, by the thirties;", "darby": "over against the twenty [cubits] that pertained to the inner court, and over against the pavement that pertained to the outer court; there was gallery against gallery in the third [story];", "twenty": "", "jps": "over against the twenty cubits which belonged to the inner court, and over against the pavement which belonged to the outer court; with gallery against gallery in three stories.", "acv": "Opposite the twenty which belonged to the inner court, and opposite the pavement which belonged to the outer court, was gallery against gallery in the third story.", "anderson": "", "haweis": "", "noyes": "over against the twenty cubits in the inner court, and over against the pavement in the outer court, was gallery before gallery, in three rows.", "webster": "Over against the twenty [cubits] which [were] for the inner court, and over against the pavement which [was] for the outer court, [was] gallery against gallery in three [stories].", "vulgate": "contra viginti cubitos atrii interioris et contra pavimentum stratum lapide atrii exterioris ubi erat porticus iuncta porticui triplici;", "brenton": "ornamented accordingly as the gates of the inner court, and arranged accordingly as the peristyles of the outer court, with triple porticos fronting one another."}}, {"v": 4, "ref": "42:4", "o": "וְ/לִ/פְנֵ֨י הַ/לְּשָׁכ֜וֹת מַהֲלַךְ֩ עֶ֨שֶׂר אַמּ֥וֹת רֹ֨חַב֙ אֶל הַ/פְּנִימִ֔ית דֶּ֖רֶךְ אַמָּ֣ה אֶחָ֑ת וּ/פִתְחֵי/הֶ֖ם לַ/צָּפֽוֹן", "en": {"kjv": "And before the chambers was a walk of ten cubits breadth inward, a way of one cubit; and their doors toward the north.", "web": "Before the rooms was a walk of ten cubits’ breadth inward, a way of one cubit; and their doors were toward the north.", "bsb": "In front of the chambers was an inner walkway ten cubits wide and a hundred cubits long. Their doors were on the north.", "asv": "And before the chambers was a walk of ten cubits’ breadth inward, a way of one cubit; and their doors were toward the north.", "ylt": "And at the front of the chambers is a walk of ten cubits in breadth unto the inner part, a way of one cubit, and their openings are at the north.", "dra": "And before the chambers was a walk ten cubits broad, looking to the inner parts of a way of one cubit. And their doors were toward the north.", "bbe": "And in front of the rooms was a walk, ten cubits wide and a hundred cubits long; and their doors were facing north.", "geneva": "And before the chambers was a gallery of ten cubites wide, and within was a way of one cubite, and their doores towarde the North.", "wycliffe": "And bifor the tresories was a walkyng of ten cubitis of breede, biholdynge to the ynnere thingis of the weie of o cubit. And the doris of tho to the north,", "rotherham": "and before the chambers, was a walk ten cubits in breadth inward, a way of one cubit,—and their entrances were to the north.", "darby": "and before the cells was a walk of ten cubits in breadth, [and] a way of a hundred cubits inward; and their entries were toward the north.", "twenty": "", "jps": "And before the chambers was a walk of ten cubits breadth inward, a way of one cubit; and their doors were toward the north.", "acv": "And before the chambers was a walk of ten cubits' breadth inward, a way of one cubit, and their doors were toward the north.", "anderson": "", "haweis": "", "noyes": "And before the chambers was a walk of ten cubits breadth inward, a way of one cubit; and their doors were toward the north.", "webster": "And before the chambers [was] a walk of ten cubits breadth inward, a way of one cubit; and their doors towards the north.", "vulgate": "et ante gazofilacia deambulatio decem cubitorum latitudinis ad interiora respiciens viae cubiti unius et ostia earum ad aquilonem;", "brenton": "And in front of the chambers was a walk ten cubits in breadth, the length reaching to a hundred cubits; and their doors were northward."}}, {"v": 5, "ref": "42:5", "o": "וְ/הַ/לְּשָׁכ֥וֹת הָ/עֶלְיוֹנֹ֖ת קְצֻר֑וֹת כִּֽי יוֹכְל֨וּ אַתִּיקִ֜ים מֵ/הֵ֗נָה מֵֽ/הַ/תַּחְתֹּנ֛וֹת וּ/מֵ/הַ/תִּֽכֹנ֖וֹת בִּנְיָֽן", "en": {"kjv": "Now the upper chambers were shorter: for the galleries were higher than these, than the lower, and than the middlemost of the building.", "web": "Now the upper rooms were shorter; for the galleries took away from these, more than from the lower and the middle, in the building.", "bsb": "Now the upper chambers were smaller because the galleries took more space from the chambers on the lower and middle floors of the building.", "asv": "Now the upper chambers were shorter; for the galleries took away from these, more than from the lower and the middlemost, in the building.", "ylt": "And the upper chambers are short, for the galleries contain more than these, than the lower, and than the middle one, of the building;", "dra": "Where were the store chambers lower above: because they bore up the galleries, which appeared above out of them from he lower parts, and from the midst of the building.", "bbe": "And the higher rooms were shorter: for the covered ways took up more space from these than from the lower and middle rooms.", "geneva": "Nowe the chambers aboue were narower: for those chambers seemed to eate vp these, to wit, the lower, and those that were in the middes of the building.", "wycliffe": "where tresories weren lowere in the hiyere thingis; for tho baren vp the porchis that apperiden an hiy of tho fro the lowere thingis, and fro the myddil thingis of the bildyng.", "rotherham": "Now, the highest chambers, were shortened,—because the galleries took away therefrom more than from the lowest or from the middle in structure.", "darby": "And the upper cells, because the galleries encroached on them, were shorter than the lower, and than the middle-most of the building.", "twenty": "", "jps": "Now the upper chambers were shorter; for the galleries took away from these, more than from the lower and the middlemost, in the building.", "acv": "Now the upper chambers were shorter, for the galleries took away from these, more than from the lower and the middlemost, in the building.", "anderson": "", "haweis": "", "noyes": "And the upper rooms were narrower (for the galleries took away room from them) than the lower and middle chambers of the building.", "webster": "Now the upper chambers [were] shorter: for the galleries were higher than these, than the lower, and than the middlemost of the building.", "vulgate": "ubi erant gazofilacia in superioribus humiliora quia subportabant porticus quae ex illis eminebant de inferioribus et de mediis aedificii;", "brenton": "And the upper walks were in like manner: for the peristyle projected from it, even from the range of columns below, and there was a space between; so were there a peristyle and a space between, and so were there two porticos."}}, {"v": 6, "ref": "42:6", "o": "כִּ֤י מְשֻׁלָּשׁוֹת֙ הֵ֔נָּה וְ/אֵ֤ין לָ/הֶן֙ עַמּוּדִ֔ים כְּ/עַמּוּדֵ֖י הַ/חֲצֵר֑וֹת עַל כֵּ֣ן נֶאֱצַ֗ל מֵ/הַ/תַּחְתּוֹנ֛וֹת וּ/מֵ/הַ/תִּֽיכֹנ֖וֹת מֵ/הָ/אָֽרֶץ", "en": {"kjv": "For they were in three stories, but had not pillars as the pillars of the courts: therefore the building was straitened more than the lowest and the middlemost from the ground.", "web": "For they were in three stories, and they didn’t have pillars as the pillars of the courts: therefore the uppermost was set back more than the lowest and the middle from the ground.", "bsb": "For they were arranged in three stories, and unlike the courts, they had no pillars. So the upper chambers were set back further than the lower and middle floors.", "asv": "For they were in three stories, and they had not pillars as the pillars of the courts: therefore the uppermost was straitened more than the lowest and the middlemost from the ground.", "ylt": "for they are threefold, and they have no pillars as the pillars of the court, therefore it hath been kept back--more than the lower and than the middle one--from the ground.", "dra": "For they were of three stories, and had not pillars, as the pillars of the courts: therefore did they appear above out of the lower places, and out of the middle places, fifty cubits from the ground.", "bbe": "For they were on three floors, and they had no pillars like the pillars of the outer square; so the highest was narrower than the lowest and middle floors from the earth level.", "geneva": "For they were in three rowes, but had not pillars as the pillars of the court: therefore there was a difference from them beneath and from the middlemost, euen from the ground.", "wycliffe": "For tho weren of thre stagis, and hadden not pileris, as weren the pilers of hallis; therfor tho stoden an hiy fro the lowere thingis, and fro the myddil thingis fro erthe, bi fifti cubitis.", "rotherham": "For three stories, they were; and had not pillars like the pillars of the courts; for this cause, it differed from the lowest and from the middle, from the ground.", "darby": "For they were in three [stories], but had not pillars as the pillars of the courts; therefore [the third story] was straitened more than the lowest and the middle-most from the ground.", "twenty": "", "jps": "For they were in three stories, and they had not pillars as the pillars of the courts; therefore room was taken away from the lowest and the middlemost, in comparison with the ground.", "acv": "For they were in three stories, and they did not have pillars as the pillars of the courts. Therefore the uppermost was narrowed more than the lowest and the middlemost from the ground.", "anderson": "", "haweis": "", "noyes": "For they were in three stories; but had not pillars, as the pillars of the courts; therefore they were narrower than the lowest, and than the middlemost from the ground.", "webster": "For they [were] in three [stories], but had not pillars as the pillars of the courts: therefore [the building] was straitened more than the lowest and the middlemost from the ground.", "vulgate": "tristega enim erant et non habebant columnas sicut erant columnae atriorum propterea eminebant de inferioribus et de mediis a terra;", "brenton": "For they were triple, and they had not pillars like the pillars of the outer ones: therefore they projected from the lower ones and the middle ones from the ground."}}, {"v": 7, "ref": "42:7", "o": "וְ/גָדֵ֤ר אֲשֶׁר לַ/חוּץ֙ לְ/עֻמַּ֣ת הַ/לְּשָׁכ֔וֹת דֶּ֛רֶךְ הֶ/חָצֵ֥ר הַ/חִֽצוֹנָ֖ה אֶל פְּנֵ֣י הַ/לְּשָׁכ֑וֹת אָרְכּ֖/וֹ חֲמִשִּׁ֥ים אַמָּֽה", "en": {"kjv": "And the wall that was without over against the chambers, toward the utter court on the forepart of the chambers, the length thereof was fifty cubits.", "web": "The wall that was outside by the side of the rooms, toward the outer court before the rooms, its length was fifty cubits.", "bsb": "An outer wall in front of the chambers was fifty cubits long and ran parallel to the chambers and the outer court.", "asv": "And the wall that was without by the side of the chambers, toward the outer court before the chambers, the length thereof was fifty cubits.", "ylt": "As to the wall that is at the outside, over-against the chambers, the way of the outer-court at the front of the chambers, its length is fifty cubits;", "dra": "And the outward wall that went about by the chambers, which were towards the outward court on the forepart of the chambers, was fifty cubits long.", "bbe": "And the wall which went outside by the side of the rooms, in the direction of the outer square in front of the rooms, was fifty cubits long.", "geneva": "And the wall that was without ouer against the chambers, toward the vtter court on the forefront of the chambers, was fiftie cubites long.", "wycliffe": "And the outermore halle closynge the walkynge place was bi the treseries, that weren in the weie of the outermore halle, bifor the treseries; the lengthe therof was of fifti cubitis.", "rotherham": "And as for the wall that was without. answering to the chambers, toward the outer court facing the chambers, the length thereof was fifty cubits.", "darby": "And the wall that was without, answering to the cells, toward the outer court in the front of the cells, its length was fifty cubits:", "twenty": "", "jps": "And the wall that was without by the side of the chambers, toward the outer court in front of the chambers, the length thereof was fifty cubits.", "acv": "And the wall that was outside by the side of the chambers, toward the outer court before the chambers, the length of it was fifty cubits.", "anderson": "", "haweis": "", "noyes": "And as to the wall that was without, over against the chambers, toward the outer court, before the chambers, the length thereof was fifty cubits.", "webster": "And the wall that [was] without over against the chambers, towards the outer court on the forepart of the chambers, the length of it [was] fifty cubits.", "vulgate": "et peribolus exterior secundum gazofilacia quae erant in via atrii exterioris ante gazofilacia longitudo eius quinquaginta cubitorum;", "brenton": "And there was light without, corresponding to the chambers of the outer court looking toward the front of the northern chambers; the length of them was fifty cubits."}}, {"v": 8, "ref": "42:8", "o": "כִּֽי אֹ֣רֶךְ הַ/לְּשָׁכ֗וֹת אֲשֶׁ֛ר לֶ/חָצֵ֥ר הַ/חִֽצוֹנָ֖ה חֲמִשִּׁ֣ים אַמָּ֑ה וְ/הִנֵּ֛ה עַל פְּנֵ֥י הַ/הֵיכָ֖ל מֵאָ֥ה אַמָּֽה", "en": {"kjv": "For the length of the chambers that were in the utter court was fifty cubits: and, lo, before the temple were an hundred cubits.", "web": "For the length of the rooms that were in the outer court was fifty cubits: and behold, before the temple were one hundred cubits.", "bsb": "For the chambers on the outer court were fifty cubits long, while those facing the temple were a hundred cubits long.", "asv": "For the length of the chambers that were in the outer court was fifty cubits: and, lo, before the temple were a hundred cubits.", "ylt": "for the length of the chambers that are to the outer court is fifty cubits, and of those on the front of the temple a hundred cubits.", "dra": "For the length of the chambers of the outward court was fifty cubits: and the length before the face of the temple, a hundred cubits.", "bbe": "For the rooms in the outer square were fifty cubits long: and in front of the Temple was a space of a hundred cubits.", "geneva": "For the length of the chambers that were in the vtter court, was fiftie cubites: and loe, before the Temple were an hundreth cubites.", "wycliffe": "For the lengthe of the tresories of the outermore halle was of fifti cubitis, and the lengthe bifor the face of the temple was of an hundrid cubitis.", "rotherham": "For the length of the chambers which pertained to the outer court was fifty cubits,—and lo! in front of the temple a hundred cubits,", "darby": "for the length of the cells that were against the outer court was fifty cubits; but behold, before the temple it was a hundred cubits.", "twenty": "", "jps": "For the length of the chambers that were toward the outer court was fifty cubits; and, lo, before the temple were a hundred cubits.", "acv": "For the length of the chambers that were in the outer court was fifty cubits. And, lo, of those on the front of the temple were a hundred cubits.", "anderson": "", "haweis": "", "noyes": "For the length of the rooms that were in the outer court was fifty cubits; but before the temple it was a hundred cubits.", "webster": "For the length of the chambers that [were] in the outer court [was] fifty cubits: and lo, before the temple [were] a hundred cubits.", "vulgate": "quia longitudo erat gazofilaciorum atrii exterioris quinquaginta cubitorum et longitudo ante faciem templi centum cubitorum;", "brenton": "For the length of the chambers looking toward the inner court was fifty cubits, and these are the ones that front the others; the whole was a hundred cubits."}}, {"v": 9, "ref": "42:9", "o": "ו/מ/תחת/ה לשכות וּ/מִ/תַּ֖חַת הַ/לְּשָׁכ֣וֹת הָ/אֵ֑לֶּה ה/מבוא הַ/מֵּבִיא֙ מֵֽ/הַ/קָּדִ֔ים בְּ/בֹא֣/וֹ לָ/הֵ֔נָּה מֵֽ/הֶ/חָצֵ֖ר הַ/חִצֹנָֽה", "en": {"kjv": "And from under these chambers was the entry on the east side, as one goeth into them from the utter court.", "web": "From under these rooms was the entry on the east side, as one goes into them from the outer court.", "bsb": "And below these chambers was the entrance on the east side as one enters them from the outer court.", "asv": "And from under these chambers was the entry on the east side, as one goeth into them from the outer court.", "ylt": "And under these chambers is the entrance from the east, in one's going into them from the outer court.", "dra": "And there was under these chambers, an entrance from the east, for them that went into them out of the outward court.", "bbe": "And under these rooms was the way in from the east side, as one goes into them from the outer square at the head of the outer wall.", "geneva": "And vnder these chambers was the entrie, on the East side, as one goeth into them from the outward court.", "wycliffe": "And vndur these tresories was an entring fro the eest, of men entringe in to tho, fro the outermere halle,", "rotherham": "And from under these chambers, was the entry from the east when one goeth in by them from the outer court.", "darby": "And under these cells was the entry from the east, as one goeth into them from the outer court.", "twenty": "", "jps": "And from under these chambers was the entry on the east side, as one goeth into them from the outer court.", "acv": "And from under these chambers was the entry on the east side, as going into them from the outer court.", "anderson": "", "haweis": "", "noyes": "And under these rooms was an entry from the east, as one came to them from the outer court.", "webster": "And from under these chambers [was] the entry on the east side, as one goeth into them from the outer court.", "vulgate": "et erat subter gazofilacia haec introitus ab oriente ingredientium in ea de atrio exteriori;", "brenton": "And there were doors of these chambers for an outlet toward the east, so that one should go through them out of the outer court,"}}, {"v": 10, "ref": "42:10", "o": "בְּ/רֹ֣חַב גֶּ֣דֶר הֶ/חָצֵ֗ר דֶּ֧רֶךְ הַ/קָּדִ֛ים אֶל פְּנֵ֧י הַ/גִּזְרָ֛ה וְ/אֶל פְּנֵ֥י הַ/בִּנְיָ֖ן לְשָׁכֽוֹת", "en": {"kjv": "The chambers were in the thickness of the wall of the court toward the east, over against the separate place, and over against the building.", "web": "In the thickness of the wall of the court toward the east, before the separate place, and before the building, there were rooms.", "bsb": "On the south side along the length of the wall of the outer court were chambers adjoining the courtyard and opposite the building,", "asv": "In the thickness of the wall of the court toward the east, before the separate place, and before the building, there were chambers.", "ylt": "In the breadth of the wall of the court eastward, unto the front of the separate place, and unto the front of the building, are chambers.", "dra": "In the breadth of the outward wall of the court that was toward the east, over against the separate building, and there were chambers before the building.", "bbe": "(And he took me) to the south, and in front of the separate place and in front of the building there were rooms.", "geneva": "The chambers were in the thicknesse of the wall of the court towarde the East, ouer against the separate place, and ouer against the building.", "wycliffe": "in the brede of the wal of the halle, that was ayens the eest weie in the face of the bilding departid. And treseries weren bifore the bilding,", "rotherham": "In the thickness of the wall of the court toward the east facing the secluded place and facing the enclosing wall, were chambers.", "darby": "In the breadth of the wall of the court toward the south, before the separate place, and before the building, were cells;", "twenty": "", "jps": "In the breadth of the wall of the court toward the east, before the separate place, and before the building, there were chambers,", "acv": "In the thickness of the wall of the court toward the east, before the separate place, and before the building, there were chambers.", "anderson": "", "haweis": "", "noyes": "In the breadth of the wall of the court toward the east, before the separate place and before the building, were rooms.", "webster": "The chambers [were] in the thickness of the wall of the court towards the east, over against the separate place, and over against the building.", "vulgate": "in latitudine periboli atrii quod erat contra viam orientalem in facie aedificii separati et erant ante aedificium gazofilacia;", "brenton": "by the opening of the walk at the corner; and the south parts were toward the south, toward the remaining space, and toward the partition, and so were the chambers."}}, {"v": 11, "ref": "42:11", "o": "וְ/דֶ֨רֶךְ֙ לִ/פְנֵי/הֶ֔ם כְּ/מַרְאֵ֣ה הַ/לְּשָׁכ֗וֹת אֲשֶׁר֙ דֶּ֣רֶךְ הַ/צָּפ֔וֹן כְּ/אָרְכָּ֖/ן כֵּ֣ן רָחְבָּ֑/ן וְ/כֹל֙ מוֹצָ֣אֵי/הֶ֔ן וּ/כְ/מִשְׁפְּטֵי/הֶ֖ן וּ/כְ/פִתְחֵי/הֶֽן", "en": {"kjv": "And the way before them was like the appearance of the chambers which were toward the north, as long as they, and as broad as they: and all their goings out were both according to their fashions, and according to their doors.", "web": "The way before them was like the appearance of the rooms which were toward the north; according to their length so was their breadth: and all their exits were both according to their fashions, and according to their doors.", "bsb": "with a passageway in front of them, just like the chambers that were on the north. They had the same length and width, with similar exits and dimensions.", "asv": "And the way before them was like the appearance of the way of the chambers which were toward the north; according to their length so was their breadth: and all their egresses were both according to their fashions, and according to their doors.", "ylt": "And the way before them is as the appearance of the chambers that are northward, according to their length so is their breadth, and all their outlets, and according to their fashions, and according to their openings.", "dra": "And the way before them was like the chambers which were toward the north: they were as long as they, and as broad as they: and all the going in to them, and their fashions, and their doors were alike.", "bbe": "And there was a walk in front of them like that by the rooms on the north; they were equally long and wide; and the ways out of them were the same in design and had the same sort of doors.", "geneva": "And the way before them was after ye maner of the chambers, which were toward ye North, as long as they, and as broad as they: and all their entries were like, both according to their facions, and according to their doores.", "wycliffe": "and a weie was bifor the face of tho, bi the licnesse of treseries that weren in the weie of the north; bi the lengthe of tho, so was also the breede of tho. And al the entryng of tho, and the licnessis and doris of tho,", "rotherham": "And the way before them was like the appearance of the chambers which were toward the north, as was their length, so, was their breadth,—and all their exits were both according to their regulations, and according to their entrances.", "darby": "and a passage before them, like the appearance of the cells that were toward the north, according to their length, according to their breadth and all their goings out, and according to their fashions, and according to their doors.", "twenty": "", "jps": "with a way before them; like the appearance of the chambers which were toward the north, as long as they, and as broad as they, with all their goings out, and according to their fashions; and as their doors,", "acv": "And the way before them was like the appearance of the way of the chambers which were toward the north. According to their length so was their breadth. And all their exits were both according to their fashions, and according to their doors.", "anderson": "", "haweis": "", "noyes": "And there was a way before them similar to that before the rooms toward the north. Both their length and their breadth were the same, and all their goings out and their fashions and their doors were the same.", "webster": "And the way before them [was] like the appearance of the chambers which [were] towards the north, as long as they, [and] as broad as they: and all their goings out [were] both according to their fashions, and according to their doors.", "vulgate": "et via ante faciem eorum iuxta similitudinem gazofilaciorum quae erant in via aquilonis secundum longitudinem eorum sic et latitudo eorum et omnis introitus eorum et similitudines et ostia eorum;", "brenton": "And the walk was in front of them, according to the measures of the chambers toward the north, both according to the length of them, and according to the breadth of them, and according to all their openings, an according to all their turnings, and according to their lights, and according to their doors."}}, {"v": 12, "ref": "42:12", "o": "וּ/כְ/פִתְחֵ֣י הַ/לְּשָׁכ֗וֹת אֲשֶׁר֙ דֶּ֣רֶךְ הַ/דָּר֔וֹם פֶּ֖תַח בְּ/רֹ֣אשׁ דָּ֑רֶךְ דֶּ֗רֶךְ בִּ/פְנֵי֙ הַ/גְּדֶ֣רֶת הֲגִינָ֔ה דֶּ֥רֶךְ הַ/קָּדִ֖ים בְּ/בוֹאָֽ/ן", "en": {"kjv": "And according to the doors of the chambers that were toward the south was a door in the head of the way, even the way directly before the wall toward the east, as one entereth into them.", "web": "According to the doors of the rooms that were toward the south was a door at the head of the way, even the way directly before the wall toward the east, as one enters into them.", "bsb": "And corresponding to the doors of the chambers that were facing south, there was a door in front of the walkway that was parallel to the wall extending eastward.", "asv": "And according to the doors of the chambers that were toward the south was a door at the head of the way, even the way directly before the wall toward the east, as one entereth into them.", "ylt": "And according to the openings of the chambers that are southward is an opening at the head of the way, the way directly in the front of the wall eastward in entering them.", "dra": "According to the doors of the chambers that were towards the south: there was a door in the head of the way, which way was before the porch, separated towards the east as one entereth in.", "bbe": "And under the rooms on the south was a door at the head of the outer wall in the direction of the east as one goes in.", "geneva": "And according to ye doores of ye chambers that were towarde the South, was a doore in the corner of the way, euen the way directly before the wall toward the East, as one entreth.", "wycliffe": "weren lijk the doris of treseries that weren in the weye biholdynge to the south; a dore was in the heed of the weye, which weie was bifor the porche departid to men entringe bi the eest weie.", "rotherham": "And according to the entrances of the chambers which were toward the south, was the entrance at the head of the way—the way in the face of the covered wall, the way toward the east in entering them.", "darby": "And according to the doors of the cells that were toward the south there was a door at the head of the way, the way directly before the corresponding wall toward the east as one entereth into them.", "twenty": "", "jps": "so were also the doors of the chambers that were toward the south, there was a door in the head of the way, even the way directly before the wall, toward the way from the east, as one entereth into them.", "acv": "And according to the doors of the chambers that were toward the south was a door at the head of the way, even the way directly before the wall toward the east, as entering into them.", "anderson": "", "haweis": "", "noyes": "And so also were the doors of the rooms toward the south; there was a door at the head of the way, before the well-built wall in the way toward the east, as one entered into them.", "webster": "And according to the doors of the chambers that [were] towards the south [was] a door in the head of the way, [even] the way directly before the wall towards the east, as one entereth into them.", "vulgate": "secundum ostia gazofilaciorum quae erant in via respiciente ad notum ostium in capite viae quae via erat ante vestibulum separatum per viam orientalem ingredientibus;", "brenton": "So were the measures of the chambers toward the south, and according to the doors at the entrance of the walk, as it were the distance of a reed for light, and eastward as one went in by them."}}, {"v": 13, "ref": "42:13", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י לִֽשְׁכ֨וֹת הַ/צָּפ֜וֹן לִֽשְׁכ֣וֹת הַ/דָּרוֹם֮ אֲשֶׁ֣ר אֶל פְּנֵ֣י הַ/גִּזְרָה֒ הֵ֣נָּה לִֽשְׁכ֣וֹת הַ/קֹּ֗דֶשׁ אֲשֶׁ֨ר יֹאכְלוּ שָׁ֧ם הַ/כֹּהֲנִ֛ים אֲשֶׁר קְרוֹבִ֥ים לַֽ/יהוָ֖ה קָדְשֵׁ֣י הַ/קֳּדָשִׁ֑ים שָׁ֞ם יַנִּ֣יחוּ קָדְשֵׁ֣י הַ/קֳּדָשִׁ֗ים וְ/הַ/מִּנְחָה֙ וְ/הַ/חַטָּ֣את וְ/הָ/אָשָׁ֔ם כִּ֥י הַ/מָּק֖וֹם קָדֹֽשׁ", "en": {"kjv": "Then said he unto me, The north chambers and the south chambers, which are before the separate place, they be holy chambers, where the priests that approach unto the Lord shall eat the most holy things: there shall they lay the most holy things, and the meat offering, and the sin offering, and the trespass offering; for the place is holy.", "web": "Then he said to me, The north rooms and the south rooms, which are before the separate place, they are the holy rooms, where the priests who are near to Yahweh shall eat the most holy things: there shall they lay the most holy things, and the meal offering, and the sin offering, and the trespass offering; for the place is holy.", "bsb": "Then the man said to me, “The north and south chambers facing the temple courtyard are the holy chambers where the priests who approach the LORD will eat the most holy offerings. There they will place the most holy offerings—the grain offerings, the sin offerings, and the guilt offerings—for the place is holy.", "asv": "Then said he unto me, The north chambers and the south chambers, which are before the separate place, they are the holy chambers, where the priests that are near unto Jehovah shall eat the most holy things: there shall they lay the most holy things, and the meal-offering, and the sin-offering, and the trespass-offering; for the place is holy.", "ylt": "And he saith unto me, `The north chambers, the south chambers, that are at the front of the separate place, they are holy chambers, where the priests (who are near to Jehovah) eat the most holy things, there they place the most holy things, and the present, and the sin-offering, and the guilt-offering, for the place is holy.", "dra": "And he said to me: The chambers of the north, and the chambers of the south, which are before the separate building: they are holy chambers, in which the priests shall eat, that approach to the Lord into the holy of holies: there they shall lay the most holy things, and the offering for sin, and for trespass: for it is a holy place.", "bbe": "And he said to me, The north rooms and the south rooms in front of the separate place are the holy rooms, where the priests who come near the Lord take the most holy things for their food: there the most holy things are placed, with the meal offering and the sin-offering and the offering for error; for the place is holy.", "geneva": "The said he vnto me, The North chambers and ye South chambers which are before ye separate place, they be holy chambers, wherein the Priests that approch vnto ye Lord, shall eat the most holy things: there shall they lay the most holy things, and the meate offering, and the sinne offering, and the trespasse offring: for the place is holy.", "wycliffe": "And he seide to me, The treseries of the north, and the treseries of the south, that ben bifor the bildyng departid, these ben hooli treseries, in whiche the preestis ben clothid, that neiyen to the Lord in to the hooli of hooli thingis; there thei schulen putte the hooli of hooli thingis, and offryngis for synne, and for trespas; for it is an hooli place.", "rotherham": "Then said he unto me, The chambers of the north the chambers of the south which face the secluded place, they are the holy chambers where the priests who draw near to Yahweh shall eat the most holy things; there, shall they lay the most holy things, and the meal offering and the sin-bearer and the guilt bearer, for the place is holy!", "darby": "And he said unto me, The north cells [and] the south cells, which are before the separate place, they are holy cells, where the priests that come near unto Jehovah shall eat the most holy things; there shall they lay the most holy things, both the oblation and the sin-offering and the trespass-offering: for the place is holy.", "twenty": "", "jps": "Then said he unto me: 'The north chambers and the south chambers, which are before the separate place, they are the holy chambers, where the priests that are near unto HaShem shall eat the most holy things; there shall they lay the most holy things, and the meal-offering, and the sin-offering, and the guilt-offering; for the place is holy.", "acv": "Then he said to me, The north chambers and the south chambers, which are before the separate place, they are the holy chambers, where the priests that are near to Jehovah shall eat the most holy things. There they shall lay the most holy things, and the meal offering, and the sin offering, and the trespass offering, for the place is holy.", "anderson": "", "haweis": "", "noyes": "Then he said to me, The north rooms and the south rooms, which are before the separate place, are holy rooms, where the priests, when they come near to Jehovah, eat the most holy things. There shall they lay the most holy things, both the flour-offering and the sin-offering and the trespass-offering; for the place is holy.", "webster": "Then said he to me, The north chambers [and] the south chambers which [are] before the separate place, they [are] holy chambers, where the priests that approach to the LORD shall eat the most holy things: there shall they lay the most holy things, and the meat-offering, and the sin-offering, and the trespass-offering; for the place [is] holy.", "vulgate": "et dixit ad me gazofilacia aquilonis et gazofilacia austri quae sunt ante aedificium separatum haec sunt gazofilacia sancta in quibus vescuntur sacerdotes qui adpropinquant ad Dominum in sancta sanctorum ibi ponent sancta sanctorum et oblationem pro peccato et pro delicto locus enim sanctus est;", "brenton": "And he said to me, The chambers toward the north, and the chambers toward the south, in front of the void spaces, these are the chambers of the sanctuary, wherein the priests the sons of Sadduc, who draw night to the Lord, shall eat the most holy things: and there shall they lay the most holy things, and the meat-offering, and the sin-offerings, and the trespass-offerings; because the place is holy."}}, {"v": 14, "ref": "42:14", "o": "בְּ/בֹאָ֣/ם הַ/כֹּהֲנִ֗ים וְ/לֹֽא יֵצְא֤וּ מֵ/הַ/קֹּ֨דֶשׁ֙ אֶל הֶ/חָצֵ֣ר הַ/חִיצוֹנָ֔ה וְ/שָׁ֞ם יַנִּ֧יחוּ בִגְדֵי/הֶ֛ם אֲשֶׁר יְשָׁרְת֥וּ בָ/הֶ֖ן כִּֽי קֹ֣דֶשׁ הֵ֑נָּה ילבשו וְ/לָבְשׁוּ֙ בְּגָדִ֣ים אֲחֵרִ֔ים וְ/קָרְב֖וּ אֶל אֲשֶׁ֥ר לָ/עָֽם", "en": {"kjv": "When the priests enter therein, then shall they not go out of the holy place into the utter court, but there they shall lay their garments wherein they minister; for they are holy; and shall put on other garments, and shall approach to those things which are for the people.", "web": "When the priests enter in, then shall they not go out of the holy place into the outer court, but there they shall lay their garments in which they minister; for they are holy: and they shall put on other garments, and shall approach to that which pertains to the people.", "bsb": "Once the priests have entered the holy area, they must not go out into the outer court until they have left behind the garments in which they minister, for these are holy. They are to put on other clothes before they approach the places that are for the people.”", "asv": "When the priests enter in, then shall they not go out of the holy place into the outer court, but there they shall lay their garments wherein they minister; for they are holy: and they shall put on other garments, and shall approach to that which pertaineth to the people.", "ylt": "In the priests' going in, they come not out from the sanctuary unto the outer court, and there they place their garments with which they minister, for they are holy, and have put on other garments, and have drawn near unto that which is for the people.'", "dra": "And when the priests shall have entered in, they shall not go out of the holy places into the outward court: but there they shall lay their vestments, wherein they minister, for they are holy: and they shall put on other garments, and so they shall go forth to the people.", "bbe": "When the priests go in, they may not go out of the holy place into the outer square, and there they are to put the robes in which they do the work of the Lord's house, for they are holy: and they have to put on other clothing before they come near that which has to do with the people.", "geneva": "When the Priestes enter therein, they shall not go out of the holy place into the vtter court, but there they shall lay their garmentes wherein they minister: for they are holy, and shall put on other garmentes, and so shall approch to those things, which are for the people.", "wycliffe": "Sotheli whanne prestis han entrid, thei schulen go out of hooli thingis in to the outermore halle; and there thei schulen putte vp her clothis, in whiche thei mynystren, for tho ben hooli; and thei schulen be clothid in othere clothis, and so thei schulen go forth to the puple.", "rotherham": "When the priests enter them, then shall they not go forth out of the holy place into the outer court, but there, shall they lay their garments wherein they minister for holy they are, and shall put on other garments, and so draw near unto that which pertaineth to the people.", "darby": "When the priests enter in, they shall not go forth from the sanctuary into the outer court, but there they shall lay their garments wherein they minister, for they are holy; and they shall put on other garments, and shall approach to that which is for the people.", "twenty": "", "jps": "When the priests enter in, then shall they not go out of the holy place into the outer court, but there they shall lay their garments wherein they minister, for they are holy; and they shall put on other garments, and shall approach to that which pertaineth to the people.'", "acv": "When the priests enter in, then they shall not go out of the holy place into the outer court, but they shall lay their garments there in which they minister, for they are holy. And they shall put on other garments, and shall approach to that which pertains to the people.", "anderson": "", "haweis": "", "noyes": "When the priests enter therein, then shall they not go out of the holy place into the outer court, but shall leave there the garments in which they minister; for they are holy; and shall put on other garments, and approach to the place which belongeth to the people.", "webster": "When the priests enter therein, then shall they not go out of the holy [place] into the outer court, but there they shall lay their garments in which they minister; for they [are] holy; and shall put on other garments, and shall approach to [those things] which [are] for the people.", "vulgate": "cum autem ingressi fuerint sacerdotes non egredientur de sanctis in atrium exterius et ibi reponent vestimenta sua in quibus ministrant quia sancta sunt vestienturque vestimentis aliis et sic procedent ad populum;", "brenton": "None shall go in thither except the priests, and they shall not go forth of the holy place into the outer court, that they that draw nigh to me may be continually holy, and may not touch their garments in which they minister, with defilement, for they are holy; and they shall put on other garments whenever they come in contact with the people."}}, {"v": 15, "ref": "42:15", "o": "וְ/כִלָּ֗ה אֶת מִדּוֹת֙ הַ/בַּ֣יִת הַ/פְּנִימִ֔י וְ/הוֹצִיאַ֨/נִי֙ דֶּ֣רֶךְ הַ/שַּׁ֔עַר אֲשֶׁ֥ר פָּנָ֖י/ו דֶּ֣רֶךְ הַ/קָּדִ֑ים וּ/מְדָד֖/וֹ סָבִ֥יב סָבִֽיב", "en": {"kjv": "Now when he had made an end of measuring the inner house, he brought me forth toward the gate whose prospect is toward the east, and measured it round about.", "web": "Now when he had made an end of measuring the inner house, he brought me out by the way of the gate whose prospect is toward the east, and measured it all around.", "bsb": "Now when the man had finished measuring the interior of the temple area, he led me out by the gate that faced east, and he measured the area all around:", "asv": "Now when he had made an end of measuring the inner house, he brought me forth by the way of the gate whose prospect is toward the east, and measured it round about.", "ylt": "And he hath finished the measurements of the inner house, and hath brought me forth the way of the gate whose front is eastward, and he hath measured it all round about.", "dra": "Now when he had made an end of measuring the inner house, he brought me out by the way of the gate that looked toward the east: and he measured it on every side round about.", "bbe": "And when he had come to the end of measuring the inner house, he took me out to the doorway looking to the east, and took its measure all round.", "geneva": "Nowe when he had made an ende of measuring the inner house, he brought mee forth toward the gate whose prospect is towarde the East, and measured it round about.", "wycliffe": "And whanne he hadde fillid the mesuris of the ynnere hous, he ledde me out bi the weie of the yate that biheelde to the eest weie; and he mat it on ech side bi cumpas.", "rotherham": "And when he had ended the measurings of the inner house, then he brought me forth by way of the gate which looked toward the east,— and measured it round about on every side.", "darby": "And when he had made an end of measuring the inner house, he brought me forth toward the gate whose front was toward the east, and measured [the enclosure] round about.", "twenty": "", "jps": "Now when he had made an end of measuring the inner house, he brought me forth by the way of the gate whose prospect is toward the east, and measured it round about.", "acv": "Now when he had made an end of measuring the inner house, he brought me forth by the way of the gate whose view is toward the east, and measured it round about.", "anderson": "", "haweis": "", "noyes": "Now when he had made an end of measuring the inner house, he brought me forth to the gate, whose prospect is toward the east, and measured it round about.", "webster": "Now when he had made an end of measuring the inner house, he brought me forth towards the gate whose prospect [is] towards the east, and measured it around.", "vulgate": "cumque conplesset mensuras domus interioris eduxit me per viam portae quae respiciebat ad viam orientalem et mensus est eam undique per circuitum;", "brenton": "So the measurement of the house within was accomplished: and he brought me forth by the way of the gate that looks eastward, and measured the plan of the house round about in order."}}, {"v": 16, "ref": "42:16", "o": "מָדַ֛ד ר֥וּחַ הַ/קָּדִ֖ים בִּ/קְנֵ֣ה הַ/מִּדָּ֑ה חֲמֵשׁ אמות מֵא֥וֹת קָנִ֛ים בִּ/קְנֵ֥ה הַ/מִּדָּ֖ה סָבִֽיב", "en": {"kjv": "He measured the east side with the measuring reed, five hundred reeds, with the measuring reed round about.", "web": "He measured on the east side with the measuring reed five hundred reeds, with the measuring reed all around.", "bsb": "With a measuring rod he measured the east side to be five hundred cubits long.", "asv": "He measured on the east side with the measuring reed five hundred reeds, with the measuring reed round about.", "ylt": "He hath measured the east side with the measuring-reed, five hundred reeds, with the measuring-reed round about.", "dra": "And he measured toward the east with the measuring reed, five hundred reeds with the measuring reed round about.", "bbe": "He went round and took the measure of it on the east side with the measuring rod, five hundred, measured with the rod all round.", "geneva": "He measured the East side with the measuring rod, fiue hundreth reedes, euen with the measuring reede round about.", "wycliffe": "Forsothe he mat ayens the eest wynd with the rehed of mesure bi cumpas fyue hundrid rehedis, in a rehed of mesure bi cumpas.", "rotherham": "He measured the east side with the measuring reed,—five hundred reeds by the measuring reed round about,", "darby": "He measured the east side with the measuring-reed, five hundred reeds, with the measuring-reed round about.", "twenty": "", "jps": "He measured the east side with the measuring reed, five hundred reeds, with the measuring reed round about.", "acv": "He measured on the east side with the measuring reed, five hundred reeds, with the measuring reed round about.", "anderson": "", "haweis": "", "noyes": "He measured the east side with the measuring-reed, five hundred reeds with the measuring-reed round about.", "webster": "He measured the east side with the measuring reed, five hundred reeds, with the measuring reed around.", "vulgate": "mensus autem est contra ventum orientalem calamo mensurae quingentos calamos in calamo mensurae per circuitum;", "brenton": "And he stood behind the gate looking eastward, and measured five hundred cubits with the measuring reed."}}, {"v": 17, "ref": "42:17", "o": "מָדַ֖ד ר֣וּחַ הַ/צָּפ֑וֹן חֲמֵשׁ מֵא֥וֹת קָנִ֛ים בִּ/קְנֵ֥ה הַ/מִּדָּ֖ה סָבִֽיב", "en": {"kjv": "He measured the north side, five hundred reeds, with the measuring reed round about.", "web": "He measured on the north side five hundred reeds with the measuring reed all around.", "bsb": "He measured the north side to be five hundred cubits long.", "asv": "He measured on the north side five hundred reeds with the measuring reed round about.", "ylt": "He hath measured the north side, five hundred reeds, with the measuring reed round about.", "dra": "And he measured toward the north five hundred reeds with the measuring reed round about.", "bbe": "And he went round and took the measure of it on the north side with the measuring rod, five hundred, measured with the rod all round.", "geneva": "He measured also the Northside, fiue hundreth reedes, euen with the measuring reede rounde about.", "wycliffe": "And he mat ayens the wynd of the north fiue hundred rehedis, in the rehed of mesure bi cumpas.", "rotherham": "He measured the north side, five hundred reeds, by the measuring reed round about.", "darby": "He measured the north side, five hundred reeds, with the measuring-reed round about.", "twenty": "", "jps": "He measured the north side, five hundred reeds, with the measuring reed round about.", "acv": "He measured on the north side five hundred reeds with the measuring reed round about.", "anderson": "", "haweis": "", "noyes": "He measured the north side five hundred reeds with the measuring-reed round about.", "webster": "He measured the north side, five hundred reeds, with the measuring reed around.", "vulgate": "et mensus est contra ventum aquilonem quingentos calamos in calamo mensurae per gyrum;", "brenton": "And he turned to the north and measured in front of the north side five hundred cubits with the measuring reed."}}, {"v": 18, "ref": "42:18", "o": "אֵ֛ת ר֥וּחַ הַ/דָּר֖וֹם מָדָ֑ד חֲמֵשׁ מֵא֥וֹת קָנִ֖ים בִּ/קְנֵ֥ה הַ/מִּדָּֽה", "en": {"kjv": "He measured the south side, five hundred reeds, with the measuring reed.", "web": "He measured on the south side five hundred reeds with the measuring reed.", "bsb": "He measured the south side to be five hundred cubits long.", "asv": "He measured on the south side five hundred reeds with the measuring reed.", "ylt": "The south side he hath measured, five hundred reeds, with the measuring-reed.", "dra": "And towards the south he measured five hundred reeds with the measuring reed round about.", "bbe": "And he went round and took the measure of it on the south side with the measuring rod, five hundred, measured with the rod all round.", "geneva": "And he measured the South side fiue hundreth reedes with the measuring reede.", "wycliffe": "And at the south wynd he mat fyue hundrid rehedis, with a rehed of mesure bi cumpas.", "rotherham": "The south side, measured he,—five hundred reeds, by the measuring reed.", "darby": "He measured the south side, five hundred reeds, with the measuring-reed.", "twenty": "", "jps": "He measured the south side, five hundred reeds, with the measuring reed.", "acv": "He measured on the south side five hundred reeds with the measuring reed.", "anderson": "", "haweis": "", "noyes": "He measured the south side five hundred reeds with the measuring-reed.", "webster": "He measured the south side, five hundred reeds, with the measuring reed.", "vulgate": "et ad ventum australem mensus est quingentos calamos in calamo mensurae per circuitum;", "brenton": "And he turned to the west, and measured in front of the west side, five hundred cubits with the measuring reed."}}, {"v": 19, "ref": "42:19", "o": "סָבַ֖ב אֶל ר֣וּחַ הַ/יָּ֑ם מָדַ֛ד חֲמֵשׁ מֵא֥וֹת קָנִ֖ים בִּ/קְנֵ֥ה הַ/מִּדָּֽה", "en": {"kjv": "He turned about to the west side, and measured five hundred reeds with the measuring reed.", "web": "He turned about to the west side, and measured five hundred reeds with the measuring reed.", "bsb": "And he came around and measured the west side to be five hundred cubits long.", "asv": "He turned about to the west side, and measured five hundred reeds with the measuring reed.", "ylt": "He hath turned round unto the west side, he hath measured five hundred reeds with the measuring-reed.", "dra": "And toward the west he measured five hundred reeds, with the measuring reed.", "bbe": "And he went round and took the measure of it on the west side with the measuring rod, five hundred, measured with the rod all round.", "geneva": "He turned about also to the West side, and measured fiue hundreth reedes with the measuring reede.", "wycliffe": "And at the west wynd he mat fyue hundrid rehedis, with the rehed of mesure.", "rotherham": "He turned about to the west side,—he measured five hundred reeds, by the measuring reed.", "darby": "He turned about to the west side, [and] measured five hundred reeds with the measuring-reed.", "twenty": "", "jps": "He turned about to the west side, and measured five hundred reeds with the measuring reed.", "acv": "He turned about to the west side, and measured five hundred reeds with the measuring reed.", "anderson": "", "haweis": "", "noyes": "He turned himself also to the west side, and measured five hundred reeds with the measuring-reed.", "webster": "He turned about to the west side, [and] measured five hundred reeds, with the measuring reed.", "vulgate": "et ad ventum occidentalem mensus est quingentos calamos in calamo mensurae;", "brenton": "And he turned to the south, and measured in front of the south side, five hundred cubits by the measuring reed."}}, {"v": 20, "ref": "42:20", "o": "לְ/אַרְבַּ֨ע רוּח֜וֹת מְדָד֗/וֹ ח֤וֹמָה ל/וֹ֙ סָבִ֣יב סָבִ֔יב אֹ֚רֶךְ חֲמֵ֣שׁ מֵא֔וֹת וְ/רֹ֖חַב חֲמֵ֣שׁ מֵא֑וֹת לְ/הַבְדִּ֕יל בֵּ֥ין הַ/קֹּ֖דֶשׁ לְ/חֹֽל", "en": {"kjv": "He measured it by the four sides: it had a wall round about, five hundred reeds long, and five hundred broad, to make a separation between the sanctuary and the profane place.", "web": "He measured it on the four sides: it had a wall around it, the length five hundred, and the breadth five hundred, to make a separation between that which was holy and that which was common.", "bsb": "So he measured the area on all four sides. It had a wall all around, five hundred cubits long and five hundred cubits wide, to separate the holy from the common.", "asv": "He measured it on the four sides: it had a wall round about, the length five hundred, and the breadth five hundred, to make a separation between that which was holy and that which was common.", "ylt": "At the four sides he hath measured it, a wall is to it all round about, the length five hundred, and the breadth five hundred, to separate between the holy and the profane place.", "dra": "By the four winds he measured the wall thereof on every side round about, five hundred cubits and five hundred cubits broad, making a separation between the sanctuary and the place of the people.", "bbe": "He took its measure on the four sides: and it had a wall all round, five hundred long and five hundred wide, separating what was holy from what was common.", "geneva": "He measured it by the foure sides: it had a wall round about, fiue hundreth reedes long, and fiue hundreth broade to make a separation betweene the Sanctuarie, and the prophane place.", "wycliffe": "Bi foure wyndis he mat the wal therof on ech side bi cumpas, the lengthe of fyue hundrid, and the breede of fyue hundrid, departynge bitwixe the seyntuarie and the place of the comyn puple.", "rotherham": "Toward the four winds, measured he it a wall, had it round about on every side, in length, five hundred, and in breadth five hundred,—to make a separation, between the holy and the common.", "darby": "He measured it on the four sides; it had a wall round about, five hundred long, and five hundred broad, to make a separation between that which was holy and that which was common.", "twenty": "", "jps": "He measured it by the four sides; it had a wall round about, the length five hundred, and the breadth five hundred, to make a separation between that which was holy and that which was common.", "acv": "He measured it on the four sides. It had a wall round about, the length five hundred, and the breadth five hundred, to make a separation between that which was holy and that which was common.", "anderson": "", "haweis": "", "noyes": "On all the four sides measured he the wall round about five hundred reeds in length, and five hundred in breadth, to make a separation between the holy and the unholy place.", "webster": "He measured it by the four sides: it had a wall around, five hundred [reeds] long, and five hundred broad, to make a separation between the sanctuary and the profane place.", "vulgate": "per quattuor ventos mensus est illud murum eius undique per circuitum longitudine quingentorum cubitorum et latitudine quingentorum cubitorum dividentem inter sanctuarium et vulgi locum;", "brenton": "The four sides he measured by the same reed, and he marked out the house and the circumference of the parts round about, a space of five hundred cubits eastward, and a breadth of five hundred cubits, to make a division between the sanctuary and the outer wall, that belonged to the design of the house."}}]}, {"c": 43, "verses": [{"v": 1, "ref": "43:1", "o": "וַ/יּוֹלִכֵ֖/נִי אֶל הַ/שָּׁ֑עַר שַׁ֕עַר אֲשֶׁ֥ר פֹּנֶ֖ה דֶּ֥רֶךְ הַ/קָּדִֽים", "en": {"kjv": "Afterward he brought me to the gate, even the gate that looketh toward the east:", "web": "Afterward he brought me to the gate, even the gate that looks toward the east.", "bsb": "Then the man brought me back to the gate that faces east,", "asv": "Afterward he brought me to the gate, even the gate that looketh toward the east.", "ylt": "And he causeth me to go to the gate, the gate that is looking eastward.", "dra": "And he brought me to the gate that looked towards the east.", "bbe": "And he took me to the doorway looking to the east:", "geneva": "Afterward he brought me to the gate, euen the gate that turneth towarde the East.", "wycliffe": "And he ledde me out to the yate, that bihelde to the eest weie.", "rotherham": "Then he took me unto the gate,—even the gate that looked toward the east;", "darby": "And he brought me unto the gate, the gate which looked toward the east.", "twenty": "", "jps": "Afterward he brought me to the gate, even the gate that looketh toward the east;", "acv": "Afterward he brought me to the gate, even the gate that looks toward the east.", "anderson": "", "haweis": "", "noyes": "Then he brought me to the gate, even to the gate that looketh toward the east.", "webster": "Afterward he brought me to the gate, [even] the gate that looketh towards the east:", "vulgate": "et duxit me ad portam quae respiciebat ad viam orientalem;", "brenton": "Moreover he brought me to the gate looking eastward, and led me forth."}}, {"v": 2, "ref": "43:2", "o": "וְ/הִנֵּ֗ה כְּבוֹד֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל בָּ֖א מִ/דֶּ֣רֶךְ הַ/קָּדִ֑ים וְ/קוֹל֗/וֹ כְּ/קוֹל֙ מַ֣יִם רַבִּ֔ים וְ/הָ/אָ֖רֶץ הֵאִ֥ירָה מִ/כְּבֹדֽ/וֹ", "en": {"kjv": "And, behold, the glory of the God of Israel came from the way of the east: and his voice was like a noise of many waters: and the earth shined with his glory.", "web": "Behold, the glory of the God of Israel came from the way of the east: and his voice was like the sound of many waters; and the earth shined with his glory.", "bsb": "and I saw the glory of the God of Israel coming from the east. His voice was like the roar of many waters, and the earth shone with His glory.", "asv": "And, behold, the glory of the God of Israel came from the way of the east: and his voice was like the sound of many waters; and the earth shined with his glory.", "ylt": "And lo, the honour of the God of Israel hath come from the way of the east, and His voice is as the noise of many waters, and the earth hath shone from His honour.", "dra": "And behold the glory of the God of Israel came in by the way of the east: and his voice was like the noise of many waters, and the earth shone with his majesty.", "bbe": "And there was the glory of the God of Israel coming from the way of the east: and his voice was like the sound of great waters, and the earth was shining with his glory.", "geneva": "And beholde, the glorie of the God of Israel came from out of the East, whose voyce was like a noyse of great waters, and the earth was made light with his glorie.", "wycliffe": "And lo! the glorie of God of Israel entride bi the eest weie; and a vois was to it, as the vois of many watris, and the erthe schynede of the mageste of hym.", "rotherham": "when lo! the glory of the God of Israel coming from the way of the east,—and the sound of him, was as the sound of many waters, and the earth shone with his glory.", "darby": "And behold, the glory of theGod of Israel came from the way of the east; and his voice was like the voice of many waters; and the earth was lit up with his glory.", "twenty": "", "jps": "and, behold, the glory of the G-d of Israel came from the way of the east; and His voice was like the sound of many waters; and the earth did shine with His glory.", "acv": "And, behold, the glory of the God of Israel came from the way of the east. And his voice was like the sound of many waters, and the earth shone with his glory.", "anderson": "", "haweis": "", "noyes": "And behold, the glory of the God of Israel came from the east; and the sound thereof was as the sound of great waters, and the earth shone with his glory.", "webster": "And behold, the glory of the God of Israel came from the way of the east: and his voice [was] like a noise of many waters: and the earth shined with his glory.", "vulgate": "et ecce gloria Dei Israhel ingrediebatur per viam orientalem et vox erat ei quasi vox aquarum multarum et terra splendebat a maiestate eius;", "brenton": "And, behold, the glory of the God of Israel came by the eastern way; and there was a voice of an army, as the sound of many redoubling their shouts, and the earth shone like light from the glory round about."}}, {"v": 3, "ref": "43:3", "o": "וּ/כְ/מַרְאֵ֨ה הַ/מַּרְאֶ֜ה אֲשֶׁ֣ר רָאִ֗יתִי כַּ/מַּרְאֶ֤ה אֲשֶׁר רָאִ֨יתִי֙ בְּ/בֹאִ/י֙ לְ/שַׁחֵ֣ת אֶת הָ/עִ֔יר וּ/מַרְא֕וֹת כַּ/מַּרְאֶ֕ה אֲשֶׁ֥ר רָאִ֖יתִי אֶל נְהַר כְּבָ֑ר וָ/אֶפֹּ֖ל אֶל פָּנָֽ/י", "en": {"kjv": "And it was according to the appearance of the vision which I saw, even according to the vision that I saw when I came to destroy the city: and the visions were like the vision that I saw by the river Chebar; and I fell upon my face.", "web": "It was according to the appearance of the vision which I saw, even according to the vision that I saw when I came to destroy the city; and the visions were like the vision that I saw by the river Chebar; and I fell on my face.", "bsb": "The vision I saw was like the vision I had seen when He came to destroy the city and like the visions I had seen by the River Kebar. I fell facedown,", "asv": "And it was according to the appearance of the vision which I saw, even according to the vision that I saw when I came to destroy the city; and the visions were like the vision that I saw by the river Chebar; and I fell upon my face.", "ylt": "And according to the appearance is the appearance that I saw, as the appearance that I saw in my coming in to destroy the city, and the appearances are as the appearance that I saw at the river Chebar, and I fall on my face.", "dra": "And I saw the vision according to the appearance which I had seen when he came to destroy the city: and the appearance was according to the vision which I had seen by the river Chobar: and I fell upon my face.", "bbe": "And the vision which I saw was like the vision I had seen when he came for the destruction of the town: and like the vision which I saw by the river Chebar; and I went down on my face.", "geneva": "And the vision which I saw was like the vision, euen as the vision that I sawe when I came to destroy the citie: and the visions were like the vision that I sawe by the riuer Chebar: and I fell vpon my face.", "wycliffe": "And Y siy a visioun, bi the licnesse whiche Y hadde seyn, whanne he cam to distrie the citee; and the licnesse was lijc the biholdyng whiche Y hadde seyn bisidis the flood Chobar.", "rotherham": "And it was like the appearance of the vision which I had seen like the vision which I saw—when I came in to destroy the city, also the visions were like the vision which I saw by the river Chebar,—so I fell upon my face.", "darby": "And the appearance of the vision that I saw was according to the vision that I had seen when I came to destroy the city; and the visions were like the vision that I saw by the river Chebar: and I fell upon my face.", "twenty": "", "jps": "And the appearance of the vision which I saw was like the vision that I saw when I came to destroy the city; and the visions were like the vision that I saw by the river Chebar; and I fell upon my face.", "acv": "And it was according to the appearance of the vision which I saw, even according to the vision that I saw when I came to destroy the city. And the visions were like the vision that I saw by the river Chebar. And I fell upon my face.", "anderson": "", "haweis": "", "noyes": "And the appearance was like the vision which I saw, like the vision which I saw when I came to destroy the city; it was a vision like the vision which I saw at the river Chebar. And I fell upon my face.", "webster": "And [it was] according to the appearance of the vision which I saw, [even] according to the vision that I saw when I came to destroy the city: and the visions [were] like the vision that I saw by the river Kebar; and I fell upon my face.", "vulgate": "et vidi visionem secundum speciem quam videram quando venit ut disperderet civitatem et species secundum aspectum quem videram iuxta fluvium Chobar et cecidi super faciem meam;", "brenton": "And the vision which I saw was like the vision which I saw when I went in to anoint the city: and the vision of the chariot which I saw was like the vision which I saw at the river Chobar; and I fell upon my face."}}, {"v": 4, "ref": "43:4", "o": "וּ/כְב֥וֹד יְהוָ֖ה בָּ֣א אֶל הַ/בָּ֑יִת דֶּ֣רֶךְ שַׁ֔עַר אֲשֶׁ֥ר פָּנָ֖י/ו דֶּ֥רֶךְ הַ/קָּדִֽים", "en": {"kjv": "And the glory of the Lord came into the house by the way of the gate whose prospect is toward the east.", "web": "Yahweh’s glory came into the house by the way of the gate whose prospect is toward the east.", "bsb": "and the glory of the LORD entered the temple through the gate facing east.", "asv": "And the glory of Jehovah came into the house by the way of the gate whose prospect is toward the east.", "ylt": "And the honour of Jehovah hath come in unto the house, the way of the gate whose face is eastward.", "dra": "And the majesty of the Lord went into the temple by the way of the gate that looked to the east.", "bbe": "And the glory of the Lord came into the house by the way of the doorway looking to the east.", "geneva": "And the glorie of the Lord came into the house by the way of the gate, whose prospect is towarde the East.", "wycliffe": "And Y felle doun on my face, and the mageste of the Lord entride in to the temple, bi the weie of the yate that biheeld to the eest.", "rotherham": "And the glory of Yahweh entered into the house,—by way of the gate which looked toward the east.", "darby": "And the glory of Jehovah came into the house by the way of the gate whose front was toward the east.", "twenty": "", "jps": "And the glory of HaShem came into the house by the way of the gate whose prospect is toward the east.", "acv": "And the glory of Jehovah came into the house by the way of the gate whose view is toward the east.", "anderson": "", "haweis": "", "noyes": "And the glory of Jehovah came into the house by way of the gate, whose prospect was toward the east.", "webster": "And the glory of the LORD came into the house by the way of the gate whose prospect [is] towards the east.", "vulgate": "et maiestas Domini ingressa est templum per viam portae quae respiciebat ad orientem;", "brenton": "And the glory of the Lord came into the house, by the way of the gate looking eastward."}}, {"v": 5, "ref": "43:5", "o": "וַ/תִּשָּׂאֵ֣/נִי ר֔וּחַ וַ/תְּבִיאֵ֕/נִי אֶל הֶֽ/חָצֵ֖ר הַ/פְּנִימִ֑י וְ/הִנֵּ֛ה מָלֵ֥א כְבוֹד יְהוָ֖ה הַ/בָּֽיִת", "en": {"kjv": "So the spirit took me up, and brought me into the inner court; and, behold, the glory of the Lord filled the house.", "web": "The Spirit took me up, and brought me into the inner court; and behold, Yahweh’s glory filled the house.", "bsb": "Then the Spirit lifted me up and brought me into the inner court, and the glory of the LORD filled the temple.", "asv": "And the Spirit took me up, and brought me into the inner court; and, behold, the glory of Jehovah filled the house.", "ylt": "And take me up doth the Spirit, and bringeth me in unto the inner court, and lo, the honour of Jehovah hath filled the house.", "dra": "And the spirit lifted me up and brought me into the inner court: and behold the house was filled with the glory of the Lord.", "bbe": "And the spirit, lifting me up, took me into the inner square; and I saw that the house was full of the glory of the Lord.", "geneva": "So the Spirite tooke me vp and brought me into the inner court, and beholde, the glorie of the Lord filled the house.", "wycliffe": "And the Spirit reiside me, and ledde me in to the ynnere halle; and lo! the hous was fillid of the glorie of the Lord.", "rotherham": "So then the spirit lifted me up, and brought me into the inner court,—and lo! the glory of Yahweh filled the house.", "darby": "And the Spirit lifted me up, and brought me into the inner court; and behold, the glory of Jehovah filled the house.", "twenty": "", "jps": "And a spirit took me up, and brought me into the inner court; and, behold, the glory of HaShem filled the house.", "acv": "And the Spirit took me up, and brought me into the inner court, and, behold, the glory of Jehovah filled the house.", "anderson": "", "haweis": "", "noyes": "Then the spirit took me up and brought me into the inner court; and behold, the glory of Jehovah filled the house.", "webster": "So the spirit took me up, and brought me into the inner court; and behold, the glory of the LORD filled the house.", "vulgate": "et levavit me spiritus et introduxit me in atrium interius et ecce repleta erat gloria Domini domus;", "brenton": "And the Spirit took me up, and brought me into the inner court; and, behold, the house of the Lord was full of glory."}}, {"v": 6, "ref": "43:6", "o": "וָ/אֶשְׁמַ֛ע מִדַּבֵּ֥ר אֵלַ֖/י מֵ/הַ/בָּ֑יִת וְ/אִ֕ישׁ הָיָ֥ה עֹמֵ֖ד אֶצְלִֽ/י", "en": {"kjv": "And I heard him speaking unto me out of the house; and the man stood by me.", "web": "I heard one speaking to me out of the house; and a man stood by me.", "bsb": "While the man was standing beside me, I heard someone speaking to me from inside the temple,", "asv": "And I heard one speaking unto me out of the house; and a man stood by me.", "ylt": "And I hear one speaking unto me from the house, and a man hath been standing near me,", "dra": "And I heard one speaking to me out of the house, and the man that stood by me,", "bbe": "And the voice of one talking to me came to my ears from inside the house; and the man was by my side.", "geneva": "And I heard one speaking vnto me out of the house: and there stoode a man by me,", "wycliffe": "And Y herde oon spekynge to me of the hous. And the man that stood bisidis me,", "rotherham": "Then heard I one speaking unto me. out of the house,—and a man, there was standing beside me.", "darby": "And I heard one speaking unto me out of the house; and a man was standing by me.", "twenty": "", "jps": "And I heard one speaking unto me out of the house; and a man stood by me.", "acv": "And I heard speaking to me out of the house, and a man stood by me.", "anderson": "", "haweis": "", "noyes": "And I heard one speaking to me out of the house, and a man was standing by me.", "webster": "And I heard [him] speaking to me out of the house; and the man stood by me.", "vulgate": "et audivi loquentem ad me de domo et vir qui stabat iuxta me;", "brenton": "And I stood, and behold there was a voice out of the house of one speaking to me, and a man stood near me,"}}, {"v": 7, "ref": "43:7", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י בֶּן אָדָם֙ אֶת מְק֣וֹם כִּסְאִ֗/י וְ/אֶת מְקוֹם֙ כַּפּ֣וֹת רַגְלַ֔/י אֲשֶׁ֧ר אֶשְׁכָּן שָׁ֛ם בְּ/ת֥וֹךְ בְּנֵֽי יִשְׂרָאֵ֖ל לְ/עוֹלָ֑ם וְ/לֹ֣א יְטַמְּא֣וּ ע֣וֹד בֵּֽית יִ֠שְׂרָאֵל שֵׁ֣ם קָדְשִׁ֞/י הֵ֤מָּה וּ/מַלְכֵי/הֶם֙ בִּ/זְנוּתָ֔/ם וּ/בְ/פִגְרֵ֥י מַלְכֵי/הֶ֖ם בָּמוֹתָֽ/ם", "en": {"kjv": "And he said unto me, Son of man, the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel for ever, and my holy name, shall the house of Israel no more defile, neither they, nor their kings, by their whoredom, nor by the carcases of their kings in their high places.", "web": "He said to me, Son of man,this is the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel forever. The house of Israel shall no more defile my holy name, neither they, nor their kings, by their prostitution, and by the dead bodies of their kings in their high places;", "bsb": "and He said to me, “Son of man, this is the place of My throne and the place for the soles of My feet, where I will dwell among the Israelites forever. The house of Israel will never again defile My holy name—neither they nor their kings—by their prostitution and by the funeral offerings for their kings at their deaths.", "asv": "And he said unto me, Son of man, this is the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel for ever. And the house of Israel shall no more defile my holy name, neither they, nor their kings, by their whoredom, and by the dead bodies of their kings in their high places;", "ylt": "and He saith unto me: `Son of man, the place of My throne, And the place of the soles of My feet, Where I dwell in the midst of the sons of Israel to the age, Defile no more do the house of Israel My holy name, They, and their kings, by their whoredom, And by the carcases of their kings--their high places.", "dra": "Said to me: Son of man, the place of my throne, and the place of the soles of my feet, where I dwell in the midst of the children of Israel for ever: and the house of Israel shall no more profane my holy name, they and their kings by their fornications, and by the carcasses of their kings, and by the high places.", "bbe": "And he said to me, Son of man, this is the place where the seat of my power is and the resting-place of my feet, where I will be among the children of Israel for ever: and no longer will the people of Israel make my holy name unclean, they or their kings, by their loose ways and by the dead bodies of their kings;", "geneva": "Which saide vnto me, Sonne of man, this place is my throne, and the place of the soles of my feete, whereas I will dwell among the children of Israel for euer, and the house of Israel shall no more defile mine holy Name, neither they, nor their Kings by their fornication, nor by the carkeises of their Kings in their high places.", "wycliffe": "seide to me, Thou, son of man, this is the place of my seete, and the place of the steppis of my feet, where Y dwelle in the myddis of the sones of Israel withouten ende; and the hous of Israel schulen no more defoule myn hooli name, thei, and the kyngis of hem in her fornicaciouns, and in the fallyngis of her kyngis, and in hiy places.", "rotherham": "Then said he unto me, Son of man This is the place of my throne and the place of the soles of my feet where I would dwell in the midst of the sons of Israel to times age-abiding,- But the house of Israel must, no more defile my holy Name. They, nor their kings by their unchastity, and by the carcases of their kings in their high places,", "darby": "And he said unto me, Son of man, [this is] the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel for ever; and the house of Israel shall no more defile my holy name, they nor their kings, with their fornication, and with the carcases of their kings [in] their high places,", "twenty": "", "jps": "And He said unto me: 'Son of man, this is the place of My throne, and the place of the soles of My feet, where I will dwell in the midst of the children of Israel for ever; and the house of Israel shall no more defile My holy name, neither they, nor their kings, by their harlotry, and by the carcasses of their kings in their high places;", "acv": "And he said to me, Son of man, this is the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the sons of Israel forever. And the house of Israel shall no more defile my holy name, neither they, nor their kings, by their whoredom, and by the dead bodies of their kings in their high places,", "anderson": "", "haweis": "", "noyes": "And he said to me: Son of man, this is the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the sons of Israel forever; and the house of Israel shall no more pollute my holy name, neither they nor their kings, by their fornication, and by the dead bodies of their kings in their sepulchres;", "webster": "And he said to me, Son of man, the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel for ever, and my holy name, shall the house of Israel no more defile, [neither] they, nor their kings, by their lewd deeds, nor by the carcasses of their kings in their high places.", "vulgate": "dixit ad me fili hominis locus solii mei et locus vestigiorum pedum meorum ubi habito in medio filiorum Israhel in aeternum et non polluent ultra domus Israhel nomen sanctum meum ipsi et reges eorum in fornicationibus suis et in ruinis regum suorum et in excelsis;", "brenton": "and he said to me, Son of man, thou hast seen the place of my throne, and the place of the soles of my feet, in which my name shall dwell in the midst of the house of Israel for ever; and the house of Israel shall no more profane my holy name, they and their princes, by their fornication, or by the murders of their princes in the midst of them;"}}, {"v": 8, "ref": "43:8", "o": "בְּ/תִתָּ֨/ם סִפָּ֜/ם אֶת סִפִּ֗/י וּ/מְזֽוּזָתָ/ם֙ אֵ֣צֶל מְזוּזָתִ֔/י וְ/הַ/קִּ֖יר בֵּינִ֣/י וּ/בֵֽינֵי/הֶ֑ם וְ/טִמְּא֣וּ אֶת שֵׁ֣ם קָדְשִׁ֗/י בְּ/תֽוֹעֲבוֹתָ/ם֙ אֲשֶׁ֣ר עָשׂ֔וּ וָ/אֲכַ֥ל אֹתָ֖/ם בְּ/אַפִּֽ/י", "en": {"kjv": "In their setting of their threshold by my thresholds, and their post by my posts, and the wall between me and them, they have even defiled my holy name by their abominations that they have committed: wherefore I have consumed them in mine anger.", "web": "in their setting of their threshold by my threshold, and their door post beside my door post, and there was a wall between me and them; and they have defiled my holy name by their abominations which they have committed: therefore I have consumed them in my anger.", "bsb": "When they placed their threshold next to My threshold and their doorposts beside My doorposts, with only a wall between Me and them, they defiled My holy name by the abominations they committed. Therefore I have consumed them in My anger.", "asv": "in their setting of their threshold by my threshold, and their door-post beside my door-post, and there was but the wall between me and them; and they have defiled my holy name by their abominations which they have committed: wherefore I have consumed them in mine anger.", "ylt": "In their putting their threshold with My threshold, And their door-post near My door-post, And the wall between Me and them, And they have defiled My holy name, By their abominations that they have done, And I consume them in Mine anger.", "dra": "They who have set their threshold by my threshold, and their posts by my posts: and there was but a wall between me, and them: and they profaned my holy name by the abominations which they committed: for which reason I consumed them in my wrath.", "bbe": "By putting their doorstep by my doorstep, and the pillar of their door by the pillar of my door, with only a wall between me and them; and they have made my holy name unclean by the disgusting things which they have done: so in my wrath I sent destruction on them.", "geneva": "Albeit they set their thresholdes by my thresholdes, and their postes by my postes (for there was but a wall betweene me and them) yet haue they defiled mine holy Name with their abominations, that they haue committed: wherfore I haue consumed them in my wrath.", "wycliffe": "Whiche maden her threisfold bisidis my threisfold, and her postis bisidis my postis, and a wal was bitwixe me and hem; and thei defouliden myn hooli name in abhomynaciouns whiche thei diden; wherfor Y wastide hem in my wraththe.", "rotherham": "When they placed— Their threshold by my threshold and their door-post beside my door-post, With, only the wall, between me and them, then defiled they my holy Name by their abominations which they committed, Wherefore I devoured them in mine anger.", "darby": "in that they set their threshold by my threshold, and their post by my post, and [there was only] a wall between me and them, and they defiled my holy name with their abominations which they committed; and I consumed them in mine anger.", "twenty": "", "jps": "in their setting of their threshold by My threshold, and their door-post beside My door-post, and there was but the wall between Me and them; and they have defiled My holy name by their abominations which they have committed; wherefore I have consumed them in Mine anger.", "acv": "in their setting of their threshold by my threshold, and their door-post beside my door-post, and there was but the wall between me and them. And they have defiled my holy name by their abominations which they have committed. Therefore I have consumed them in my anger.", "anderson": "", "haweis": "", "noyes": "in that they set their threshold by my threshold, and their post near my post, so that there was only a wall between me and them, and defiled my holy name by the abominations which they committed; wherefore I have consumed them in my anger.", "webster": "In their setting of their threshhold by my threshholds, and their post by my posts, and the wall between me and them, they have even defiled my holy name by their abominations that they have committed: wherefore I have consumed them in my anger.", "vulgate": "qui fabricati sunt limen suum iuxta limen meum et postes suos iuxta postes meos et murus erat inter me et eos et polluerunt nomen sanctum meum in abominationibus quas fecerunt propter quod consumpsi eos in ira mea;", "brenton": "when they set my door-way by their door-way, and my thresholds near to their thresholds: and they made my wall as it were joining myself and them, and they profaned my holy name with their iniquities which they wrought: and I destroyed them in my wrath and with slaughter."}}, {"v": 9, "ref": "43:9", "o": "עַתָּ֞ה יְרַחֲק֧וּ אֶת זְנוּתָ֛/ם וּ/פִגְרֵ֥י מַלְכֵי/הֶ֖ם מִמֶּ֑/נִּי וְ/שָׁכַנְתִּ֥י בְ/תוֹכָ֖/ם לְ/עוֹלָֽם", "en": {"kjv": "Now let them put away their whoredom, and the carcases of their kings, far from me, and I will dwell in the midst of them for ever.", "web": "Now let them put away their prostitution, and the dead bodies of their kings, far from me; and I will dwell in their midst forever.", "bsb": "Now let them remove far from Me their prostitution and the funeral offerings for their kings, and I will dwell among them forever.", "asv": "Now let them put away their whoredom, and the dead bodies of their kings, far from me; and I will dwell in the midst of them for ever.", "ylt": "Now do they put far off their whoredom, And the carcases of their kings--from Me, And I have dwelt in their midst to the age.", "dra": "Now therefore let them put away their fornications, and the carcasses of their kings far from me: and I will dwell in the midst of them for ever.", "bbe": "Now let them put their loose ways and the dead bodies of their kings far from me, and I will be among them for ever.", "geneva": "Now therefore let them put away their fornication, and the carkeises of their Kings farre from me, and I will dwell among them for euer.", "wycliffe": "Now therfor putte thei awei fer her fornicacioun, and the fallyng of her kyngis fro me; and Y schal dwelle euere in the myddis of hem.", "rotherham": "Now, let them remove their unchastity and the carcases of their kings far from me,- So will I make my habitation in the midst of them, to times age-abiding.", "darby": "Now let them put away their fornication, and the carcases of their kings, far from me, and I will dwell in the midst of them for ever.", "twenty": "", "jps": "Now let them put away their harlotry, and the carcasses of their kings, far from Me, and I will dwell in the midst of them for ever.", "acv": "Now let them put away their whoredom, and the dead bodies of their kings, far from me, and I will dwell in the midst of them forever.", "anderson": "", "haweis": "", "noyes": "Now let them remove far away from me their fornication, and the carcasses of their kings; and I will dwell in the midst of them forever.", "webster": "Now let them put away their lewd deeds, and the carcasses of their kings, far from me, and I will dwell in the midst of them for ever.", "vulgate": "nunc ergo repellant procul fornicationem suam et ruinas regum suorum a me et habitabo in medio eorum semper;", "brenton": "And now let them put away from me their fornication, and the murders of their princes, and I will dwell in the midst of them forever."}}, {"v": 10, "ref": "43:10", "o": "אַתָּ֣ה בֶן אָדָ֗ם הַגֵּ֤ד אֶת בֵּֽית יִשְׂרָאֵל֙ אֶת הַ/בַּ֔יִת וְ/יִכָּלְמ֖וּ מֵ/עֲוֺנֽוֹתֵי/הֶ֑ם וּ/מָדְד֖וּ אֶת תָּכְנִֽית", "en": {"kjv": "Thou son of man, shew the house to the house of Israel, that they may be ashamed of their iniquities: and let them measure the pattern.", "web": "You, son of man, show the house to the house of Israel, that they may be ashamed of their iniquities; and let them measure the pattern.", "bsb": "As for you, son of man, describe the temple to the people of Israel, so that they may be ashamed of their iniquities. Let them measure the plan,", "asv": "Thou, son of man, show the house to the house of Israel, that they may be ashamed of their iniquities; and let them measure the pattern.", "ylt": "Thou, son of man, Shew the house of Israel the house, And they are ashamed of their iniquities, And they have measured the measurement.", "dra": "But thou, son of man, shew to the house of Israel the temple, and let them be ashamed of their iniquities, and let them measure the building:", "bbe": "You, son of man, give the children of Israel an account of this house, so that they may be shamed because of their evil-doing: and let them see the vision of it and its image.", "geneva": "Thou sonne of man, shew this House to the house of Israel, that they may be ashamed of their wickednes, and let them measure ye paterne.", "wycliffe": "But thou, sone of man, schewe the temple to the hous of Israel, and be thei schent of her wickidnessis; and mete thei the bilding,", "rotherham": "Thou, son of man, Declare the house unto the house of Israel, That they may be put to the blush for their iniquities,- Then let them measure the pattern.", "darby": "Thou, son of man, shew the house to the house of Israel, that they may be confounded at their iniquities; and let them measure the pattern.", "twenty": "", "jps": "Thou, son of man, show the house to the house of Israel, that they may be ashamed of their iniquities; and let them measure accurately.", "acv": "Thou, son of man, show the house to the house of Israel, that they may be ashamed of their iniquities, and let them measure the pattern.", "anderson": "", "haweis": "", "noyes": "And thou, son of man, show this house to the house of Israel, that they may be ashamed of their iniquities, and that they may measure the pattern.", "webster": "Thou son of man, show the house to the house of Israel, that they may be ashamed of their iniquities: and let them measure the pattern.", "vulgate": "tu autem fili hominis ostende domui Israhel templum et confundantur ab iniquitatibus suis et metiantur fabricam;", "brenton": "And thou, son of man, shew the house to the house of Israel, that they may cease from their sins; and shew its aspect and the arrangement of it."}}, {"v": 11, "ref": "43:11", "o": "וְ/אִֽם נִכְלְמ֞וּ מִ/כֹּ֣ל אֲשֶׁר עָשׂ֗וּ צוּרַ֣ת הַ/בַּ֡יִת וּ/תְכוּנָת֡/וֹ וּ/מוֹצָאָ֡י/ו וּ/מוֹבָאָ֣י/ו וְֽ/כָל צֽוּרֹתָ֡/ו וְ/אֵ֣ת כָּל חֻקֹּתָי/ו֩ וְ/כָל צורת/י צ֨וּרֹתָ֤י/ו וְ/כָל תורת/ו תּוֹרֹתָי/ו֙ הוֹדַ֣ע אוֹתָ֔/ם וּ/כְתֹ֖ב לְ/עֵֽינֵי/הֶ֑ם וְ/יִשְׁמְר֞וּ אֶת כָּל צוּרָת֛/וֹ וְ/אֶת כָּל חֻקֹּתָ֖י/ו וְ/עָשׂ֥וּ אוֹתָֽ/ם", "en": {"kjv": "And if they be ashamed of all that they have done, shew them the form of the house, and the fashion thereof, and the goings out thereof, and the comings in thereof, and all the forms thereof, and all the ordinances thereof, and all the forms thereof, and all the laws thereof: and write it in their sight, that they may keep the whole form thereof, and all the ordinances thereof, and do them.", "web": "If they be ashamed of all that they have done, make known to them the form of the house, and its fashion, and its exits, and its entrances, and all its forms, and all its ordinances, and all its forms, and all its laws; and write it in their sight; that they may keep the whole form of it, and all its ordinances, and do them.", "bsb": "and if they are ashamed of all they have done, then make known to them the design of the temple—its arrangement and its exits and entrances—its whole design along with all its statutes, forms, and laws. Write it down in their sight, so that they may keep its complete design and all its statutes and may carry them out.", "asv": "And if they be ashamed of all that they have done, make known unto them the form of the house, and the fashion thereof, and the egresses thereof, and the entrances thereof, and all the forms thereof, and all the ordinances thereof, and all the forms thereof, and all the laws thereof; and write it in their sight; that they may keep the whole form thereof, and all the ordinances thereof, and do them.", "ylt": "And since they have been ashamed of all that they have done, The form of the house, and its measurement, And its outlets, and its inlets, and all its forms, And all its statutes, even all its forms, And all its laws cause them to know, And write it before their eyes, And they observe all its forms, And all its statutes, and have done them.", "dra": "And be ashamed of all that they have done. Shew them the form of the house, and of the fashion thereof, the goings out and the comings in, and the whole plan thereof, and all its ordinances, and all its order, and all its laws, and thou shalt write it in their sight: that they may keep the whole form thereof, and its ordinances, and do them.", "bbe": "And they will be shamed by what they have done; so give them the knowledge of the form of the house and its structure, and the ways out of it and into it, and all its laws and its rules, writing it down for them: so that they may keep all its laws and do them.", "geneva": "And if they be ashamed of all that they haue done, shew them the forme of the House, and ye paterne thereof, and the going out thereof, and the coming in thereof, and the whole fashion thereof, and all the ordinances thereof, and all the figures thereof, and all the lawes thereof: and write it in their sight, that they may keepe the whole fashion thereof, and all the ordinances thereof, and do them.", "wycliffe": "and be thei aschamed of alle thingis whiche thei diden. Thou schalt schewe to hem, and thou schalt write bifore the iyen of hem the figure of the hous, and of the bildyng therof; the outgoyngis, and the entryngis, and al the discryuyng therof, and alle the comaundementis therof, and al the ordre therof, `and alle the lawis therof; that thei kepe alle the discryuyngis therof, and comaundementis therof, and do tho.", "rotherham": "And when they have blushed for all that they have done, then The form of the house. And the arrangement thereof And the exits thereof. And the entrances thereof And all the forms thereof, and all the statutes thereof. And all the forms thereof and all the laws thereof, make thou known unto them, And write [it] before their eyes; That they may keep— All the forms thereof And all the statutes thereof. And do them.", "darby": "And if they be confounded at all that they have done, make known to them the form of the house, and its fashion, and its goings out, and its comings in, and all its forms, and all its statutes, yea, all the forms thereof, and all the laws thereof; and write it in their sight, that they may keep the whole form thereof, and all the statutes thereof, and do them.", "twenty": "", "jps": "And if they be ashamed of all that they have done, make known unto them the form of the house, and the fashion thereof, and the goings out thereof, and the comings in thereof, and all the forms thereof, and all the ordinances thereof, and all the forms thereof, and all the laws thereof, and write it in their sight; that they may keep the whole form thereof, and all the ordinances thereof, and do them.", "acv": "And if they be ashamed of all that they have done, make known to them the form of the house, and the fashion of it, and the exits of it, and the entrances of it, and all the forms of it, and all the ordinances of it, and all the forms of it, and all the laws of it. And write it in their sight, that they may keep the whole form of it, and all the ordinances of it, and do them.", "anderson": "", "haweis": "", "noyes": "And if they be ashamed of all which they have done, let them know the form of the house and the fashion thereof, and the passages for going out and coming in, and all the forms thereof, and all the statutes thereof, and all the laws thereof, and write it in their sight, that they may keep the whole form thereof, and all the statutes thereof, and do them.", "webster": "And if they shall be ashamed of all that they have done, show them the form of the house, and the fashion of it, and its goings out, and its comings in, and all its forms, and all its ordinances, and all its forms, and all its laws: and write [it] in their sight, that they may keep the whole form of it, and all its ordinances, and do them.", "vulgate": "et erubescant ex omnibus quae fecerunt figuram domus et fabricae eius exitus et introitus et omnem descriptionem eius et universa praecepta eius cunctumque ordinem eius et omnes leges eius ostende eis et scribes in oculis eorum et custodiant omnes descriptiones eius et praecepta illius et faciant ea;", "brenton": "And they shall bear their punishment for all the things that they have done: and thou shalt describe the house, and its entrances, and the plan thereof, and all its ordinances, and thou shalt make known to them all the regulations of it, and describe them before them: and they shall keep all my commandments, and all my ordinances, and do them."}}, {"v": 12, "ref": "43:12", "o": "זֹ֖את תּוֹרַ֣ת הַ/בָּ֑יִת עַל רֹ֣אשׁ הָ֠/הָר כָּל גְּבֻל֞/וֹ סָבִ֤יב סָבִיב֙ קֹ֣דֶשׁ קָדָשִׁ֔ים הִנֵּה זֹ֖את תּוֹרַ֥ת הַ/בָּֽיִת", "en": {"kjv": "This is the law of the house; Upon the top of the mountain the whole limit thereof round about shall be most holy. Behold, this is the law of the house.", "web": "This is the law of the house: on the top of the mountain the whole limit around it shall be most holy. Behold, this is the law of the house.", "bsb": "This is the law of the temple: All its surrounding territory on top of the mountain will be most holy. Yes, this is the law of the temple.", "asv": "This is the law of the house: upon the top of the mountain the whole limit thereof round about shall be most holy. Behold, this is the law of the house.", "ylt": "This is a law of the house: on the top of the mountain, all its border all round about is most holy; lo, this is a law of the house.", "dra": "This is the law of the house upon the top of the mountain: All its border round about; most holy: this then is the law of the house.", "bbe": "This is the law of the house: On the top of the mountain all the space round it on every side will be most holy. See, this is the law of the house.", "geneva": "This is the description of the house, It shalbe vpon the toppe of the mount: all the limites thereof round about shalbe most holy. Beholde, this is the description of the house.", "wycliffe": "This is the lawe of the hous, in the hiynesse of the hil; alle the coostis therof in cumpas is the hooli of hooli thingis; therfor this is the lawe of the hous.", "rotherham": "This shall be the law of the house,— Upon the top of the mountain, all the boundary thereof round about on every side, [shall be] most holy, Lo! this, shall be the law of the house.", "darby": "This is the law of the house: Upon the top of the mountain all its border round about is most holy. Behold, this is the law of the house.", "twenty": "", "jps": "This is the law of the house: upon the top of the mountain the whole limit thereof round about shall be most holy. Behold, this is the law of the house.", "acv": "This is the law of the house. Upon the top of the mountain the whole limit of it round about shall be most holy. Behold, this is the law of the house.", "anderson": "", "haweis": "", "noyes": "This is the law of the house. Upon the top of the mountain, all within its limits shall be most holy. Behold, this is the law of the house.", "webster": "This [is] the law of the house; Upon the top of the mountain, the whole limit of it around [shall be] most holy. Behold, this [is] the law of the house.", "vulgate": "ista est lex domus in summitate montis omnes fines eius in circuitu sanctum sanctorum est haec ergo est lex domus;", "brenton": "And thou shalt shew the plan of the house on the top of the mountain: all its limits round about shall be most holy."}}, {"v": 13, "ref": "43:13", "o": "וְ/אֵ֨לֶּה מִדּ֤וֹת הַ/מִּזְבֵּ֨חַ֙ בָּֽ/אַמּ֔וֹת אַמָּ֥ה אַמָּ֖ה וָ/טֹ֑פַח וְ/חֵ֨יק הָ/אַמָּ֜ה וְ/אַמָּה רֹ֗חַב וּ/גְבוּלָ֨/הּ אֶל שְׂפָתָ֤/הּ סָבִיב֙ זֶ֣רֶת הָ/אֶחָ֔ד וְ/זֶ֖ה גַּ֥ב הַ/מִּזְבֵּֽחַ", "en": {"kjv": "And these are the measures of the altar after the cubits: The cubit is a cubit and an hand breadth; even the bottom shall be a cubit, and the breadth a cubit, and the border thereof by the edge thereof round about shall be a span: and this shall be the higher place of the altar.", "web": "These are the measures of the altar by cubits (the cubit is a cubit and a hand breadth): the bottom shall be a cubit, and the breadth a cubit, and its border around its edge a span; and this shall be the base of the altar.", "bsb": "These are the measurements of the altar in long cubits (a cubit and a handbreadth): Its gutter shall be a cubit deep and a cubit wide, with a rim of one span around its edge. And this is the height of the altar:", "asv": "And these are the measures of the altar by cubits (the cubit is a cubit and a handbreadth): the bottom shall be a cubit, and the breadth a cubit, and the border thereof by the edge thereof round about a span; and this shall be the base of the altar.", "ylt": "`And these are measures of the altar by cubits: The cubit is a cubit and a handbreadth, and the centre is a cubit, and a cubit the breadth; and its border on its edge round about is one span, and this is the upper part of the altar.", "dra": "And these are the measures of the altar by the truest cubit, which is a cubit and a handbreadth: the bottom thereof was a cubit, and the breadth a cubit: and the border thereof unto its edge, and round about, one handbreadth: and this was the trench of the altar.", "bbe": "And these are the measures of the altar in cubits: (the cubit being a cubit and a hand's measure;) its hollow base is a cubit high and a cubit wide, and it has an overhanging edge as wide as a hand-stretch all round it:", "geneva": "And these are the measures of the Altar, after the cubites, the cubite is a cubite, and an had breadth, euen the bottome shalbe a cubite, and the breadth a cubite, and the border thereof by the edge thereof rounde about shalbe a spanne: and this shalbe the height of the altar.", "wycliffe": "Forsothe these ben the mesuris of the auter, in a verieste cubit, that hadde a cubit and a spanne; in the bosum therof was a cubit in lengthe, and a cubit in breede; and the ende therof til to the brenke, and o spanne in cumpas; also this was the diche of the auter.", "rotherham": "And these, shall be the measures of the altar, in cubits, a cubit being a cubit and a handbreadth; and the hollow, shall be a cubit, and a cubit the breadth, and the boundary thereof unto the edge thereof round about shall be a single span. And this, shall be the upper part of the altar,", "darby": "And these are the measures of the altar in cubits: the cubit is a cubit and a hand breadth. The bottom was a cubit [in height] and the breadth a cubit, and its border on the edge thereof round about, one span: and this was the base of the altar.", "twenty": "", "jps": "And these are the measures of the altar by cubits--the cubit is a cubit and a handbreadth: the bottom shall be a cubit, and the breadth a cubit, and the border thereof by the edge thereof round about a span; and this shall be the base of the altar.", "acv": "And these are the measures of the altar by cubits (the cubit is a cubit and a handbreadth). The bottom shall be a cubit, and the breadth a cubit, and the border of it by the edge of it round about a span. And this shall be the base of the altar.", "anderson": "", "haweis": "", "noyes": "And these are the measures of the altar by cubits; each cubit being a cubit and a hand-breadth. The bottom shall be a cubit high and a cubit broad; and the border thereof, by the edge thereof round about, shall be a span; and this shall be the outer part of the altar.", "webster": "And these [are] the measures of the altar after the cubits: The cubit [is] a cubit and a hand-breadth; even the bottom [shall be] a cubit, and the breadth a cubit, and the border of it by its edge around [shall be] a span: and this [shall be] the higher place of the altar.", "vulgate": "istae autem mensurae altaris in cubito verissimo qui habebat cubitum et palmum in sinu eius erat cubitus et cubitus in latitudine et definitio usque ad labium eius in circuitu palmus unus haec quoque erat fossa altaris;", "brenton": "And these are the measures of the altar by the cubit of a cubit and a span, the cavity shall be a cubit deep, and a cubit shall be the breadth, and the border on the rim of it round about shall be a span: and this shall be the height of the altar"}}, {"v": 14, "ref": "43:14", "o": "וּ/מֵ/חֵ֨יק הָ/אָ֜רֶץ עַד הָ/עֲזָרָ֤ה הַ/תַּחְתּוֹנָה֙ שְׁתַּ֣יִם אַמּ֔וֹת וְ/רֹ֖חַב אַמָּ֣ה אֶחָ֑ת וּ/מֵ/הֳ/עֲזָרָ֨ה הַ/קְּטַנָּ֜ה עַד הָ/עֲזָרָ֤ה הַ/גְּדוֹלָה֙ אַרְבַּ֣ע אַמּ֔וֹת וְ/רֹ֖חַב הָ/אַמָּֽה", "en": {"kjv": "And from the bottom upon the ground even to the lower settle shall be two cubits, and the breadth one cubit; and from the lesser settle even to the greater settle shall be four cubits, and the breadth one cubit.", "web": "From the bottom on the ground to the lower ledge shall be two cubits, and the breadth one cubit; and from the lesser ledge to the greater ledge shall be four cubits, and the breadth a cubit.", "bsb": "The space from the gutter on the ground to the lower ledge shall be two cubits, and the ledge one cubit wide. The space from the smaller ledge to the larger ledge shall be four cubits, and the ledge one cubit wide.", "asv": "And from the bottom upon the ground to the lower ledge shall be two cubits, and the breadth one cubit; and from the lesser ledge to the greater ledge shall be four cubits, and the breadth a cubit.", "ylt": "And from the centre of the ground unto the lower border is two cubits, and the breadth one cubit, and from the lesser border unto the greater border four cubits, and the breadth a cubit.", "dra": "And from the bottom of the ground to the lowest brim two cubits, and the breadth of one cubit: and from the lesser brim to the greater brim four cubits, and the breadth of one cubit.", "bbe": "And from the base on the earth level to the lower shelf, the altar is two cubits high and a cubit wide; and from the smaller shelf to the greater shelf it is four cubits high and a cubit wide.", "geneva": "And from the bottome which toucheth the ground to the lower piece shalbe two cubites: and the breadth one cubite, and from the litle piece to the great piece shalbe foure cubites, and the breadth one cubite.", "wycliffe": "And fro the bosum of the erthe til to the laste heiythe weren twei cubitis, and the breede of o cubit; and fro the lesse heiythe til to the grettere heiythe were foure cubitis, and the breede was of o cubit; forsothe thilke ariel, that is, the hiyere part of the auter, was of foure cubitis; and fro the auter `til to aboue weren foure hornes.", "rotherham": "And from the hollow of the ground unto the lower ledge, [shall be] two cubits, and the breadth, one cubit,- and from the smaller ledge unto the larger ledge, [shall be] four cubits, and the breadth, a cubit.", "darby": "And from the bottom upon the ground to the lower settle was two cubits, and the breadth one cubit; and from the small settle to the great settle, four cubits, and the breadth a cubit.", "twenty": "", "jps": "And from the bottom upon the ground to the lower settle shall be two cubits, and the breadth one cubit; and from the lesser settle to the greater settle shall be four cubits, and the breadth a cubit.", "acv": "And from the bottom upon the ground to the lower ledge shall be two cubits, and the breadth one cubit. And from the lesser ledge to the greater ledge shall be four cubits, and the breadth a cubit.", "anderson": "", "haweis": "", "noyes": "And from the bottom upon the ground to the lower ledge shall be two cubits, and the breadth one cubit; and from the lesser ledge to the greater ledge shall be four cubits, and the breadth a cubit.", "webster": "And from the bottom [upon] the ground [even] to the lower settle [shall be] two cubits, and the breadth one cubit; and from the lesser settle [even] to the greater settle [shall be] four cubits, and the breadth [one] cubit.", "vulgate": "et de sinu terrae usque ad crepidinem novissimam duo cubiti et latitudo cubiti unius et a crepidine maiori usque ad crepidinem minorem quattuor cubiti et latitudo unius cubiti;", "brenton": "from the bottom at the commencement of the hollow part to this great mercy-seat, from beneath was two cubits, and the breadth was a cubit; and from the little mercy-seat to the great mercy-seat, four cubits, and the breadth was a cubit."}}, {"v": 15, "ref": "43:15", "o": "וְ/הַֽ/הַרְאֵ֖ל אַרְבַּ֣ע אַמּ֑וֹת וּ/מֵ/הָ/אֲרִאֵ֣יל וּ/לְ/מַ֔עְלָ/ה הַ/קְּרָנ֖וֹת אַרְבַּֽע", "en": {"kjv": "So the altar shall be four cubits; and from the altar and upward shall be four horns.", "web": "The upper altar shall be four cubits; and from the altar hearth and upward there shall be four horns.", "bsb": "The altar hearth shall be four cubits high, and four horns shall project upward from the hearth.", "asv": "And the upper altar shall be four cubits; and from the altar hearth and upward there shall be four horns.", "ylt": "`And the altar is four cubits, and from the altar and upward are four horns.", "dra": "And the Ariel itself was four cubits: and from the Ariel upward were four horns.", "bbe": "And the fireplace is four cubits high: and coming up from the fireplace are the horns, a cubit high.", "geneva": "So the altar shalbe foure cubites, and from the altar vpward shalbe foure hornes.", "wycliffe": "", "rotherham": "And the hearth, [shall, be] four cubits,—and from the hearth and upward, the horns [shall be] four.", "darby": "And the upper altar was four cubits; and from the hearth ofGod and upward were four horns.", "twenty": "", "jps": "And the hearth shall be four cubits; and from the hearth and upward there shall be four horns.", "acv": "And the upper altar shall be four cubits. And from the altar hearth and upward there shall be four horns.", "anderson": "", "haweis": "", "noyes": "And the altar shall be four cubits; and from the altar upward shall be four horns.", "webster": "So the altar [shall be] four cubits; and from the altar and upward [shall be] four horns.", "vulgate": "ipse autem arihel quattuor cubitorum et ab arihel usque sursum cornua quattuor;", "brenton": "And the altar shall be four cubits; and from the altar and above the horns a cubit."}}, {"v": 16, "ref": "43:16", "o": "ו/ה/אראיל וְ/הָ/אֲרִיאֵ֗ל שְׁתֵּ֤ים עֶשְׂרֵה֙ אֹ֔רֶךְ בִּ/שְׁתֵּ֥ים עֶשְׂרֵ֖ה רֹ֑חַב רָב֕וּעַ אֶ֖ל אַרְבַּ֥עַת רְבָעָֽי/ו", "en": {"kjv": "And the altar shall be twelve cubits long, twelve broad, square in the four squares thereof.", "web": "The altar hearth shall be twelve cubits long by twelve broad, square in the four sides of it.", "bsb": "The altar hearth shall be square at its four corners, twelve cubits long and twelve cubits wide.", "asv": "And the altar hearth shall be twelve cubits long by twelve broad, square in the four sides thereof.", "ylt": "And the altar is twelve long by twelve broad, square in its four squares.", "dra": "And the Ariel was twelve cubits long, and twelve cubits broad, foursquare, with equal sides.", "bbe": "And the fireplace is twelve cubits long and twelve cubits wide, square on its four sides.", "geneva": "And the altar shalbe twelue cubites long, and twelue broade, and fouresquare in the foure corners thereof.", "wycliffe": "And the auter of twelue cubitis in lengthe was foure cornerid with euene sidis, bi twelue cubitis of breede.", "rotherham": "And the hearth shall be twelve cubits in length, by twelve in breadth—square in the four sides thereof.", "darby": "And the hearth ofGod was twelve [cubits] long, by twelve broad, square in the four sides thereof.", "twenty": "", "jps": "And the hearth shall be twelve cubits long by twelve broad, square in the four sides thereof.", "acv": "And the altar hearth shall be twelve long by twelve broad, square in the four sides of it.", "anderson": "", "haweis": "", "noyes": "And the altar shall be twelve cubits long by twelve broad; square on the four sides thereof.", "webster": "And the altar [shall be] twelve [cubits] long, twelve broad, square in the four squares of it.", "vulgate": "et arihel duodecim cubitorum in longitudine per duodecim cubitos latitudinis quadrangulatum aequis lateribus;", "brenton": "And the altar shall be of the length of twelve cubits, by twelve cubits in breadth, square upon its four sides."}}, {"v": 17, "ref": "43:17", "o": "וְ/הָ/עֲזָרָ֞ה אַרְבַּ֧ע עֶשְׂרֵ֣ה אֹ֗רֶךְ בְּ/אַרְבַּ֤ע עֶשְׂרֵה֙ רֹ֔חַב אֶ֖ל אַרְבַּ֣עַת רְבָעֶ֑י/הָ וְ/הַ/גְּבוּל סָבִ֨יב אוֹתָ֜/הּ חֲצִ֣י הָ/אַמָּ֗ה וְ/הַֽ/חֵיק לָ֤/הּ אַמָּה֙ סָבִ֔יב וּ/מַעֲלֹתֵ֖/הוּ פְּנ֥וֹת קָדִֽים", "en": {"kjv": "And the settle shall be fourteen cubits long and fourteen broad in the four squares thereof; and the border about it shall be half a cubit; and the bottom thereof shall be a cubit about; and his stairs shall look toward the east.", "web": "The ledge shall be fourteen cubits long by fourteen broad in the four sides of it; and the border about it shall be half a cubit; and its bottom shall be a cubit around; and its steps shall look toward the east.", "bsb": "The ledge shall also be square, fourteen cubits long and fourteen cubits wide, with a rim of half a cubit and a gutter of a cubit all around it. The steps of the altar shall face east.”", "asv": "And the ledge shall be fourteen cubits long by fourteen broad in the four sides thereof; and the border about it shall be half a cubit; and the bottom thereof shall be a cubit round about; and the steps thereof shall look toward the east.", "ylt": "And the border is fourteen long by fourteen broad, at its four squares, and the border round about it is half a cubit, and the centre to it is a cubit round about, and its steps are looking eastward.'", "dra": "And the brim was fourteen cubits long, and fourteen cubits broad in the four corners thereof: and the crown round about it was half a cubit, and the bottom of it one cubit round about: and its steps turned toward the east.", "bbe": "And the shelf is fourteen cubits long and fourteen cubits wide, on its four sides; the edge round it is half a cubit; the base of it is a cubit all round, and its steps are facing the east.", "geneva": "And ye frame shalbe foureteene cubites log, and fourteene broade in the fouresquare corners thereof, and the border about it shalbe halfe a cubite, and the bottome therof shalbe a cubite about, and the steps thereof shalbe turned towarde ye East.", "wycliffe": "And the heiythe of fourtene cubitis of lengthe was bi fourtene cubitis of breede, in foure corneris therof. And a coroun of half a cubit was in the cumpas therof, and the bosum therof was of o cubit bi cumpas; forsothe the degrees therof weren turned to the eest.", "rotherham": "And the ledge shall be fourteen in length, by fourteen in breadth, unto the four sides thereof,—and the boundary round about it shall be half a cubit and, the hollow thereto, a cubit round about, with, the steps thereof, looking toward the east.", "darby": "And the settle was fourteen [cubits] long by fourteen broad in the four sides thereof; and the border about it, half a cubit; and the bottom thereof a cubit round about: and its steps looked toward the east.", "twenty": "", "jps": "And the settle shall be fourteen cubits long by fourteen broad in the four sides thereof; and the border about it shall be half a cubit; and the bottom thereof shall be a cubit about; and the steps thereof shall look toward the east.'", "acv": "And the ledge shall be fourteen long by fourteen broad in the four sides of it. And the border about it shall be half a cubit, and the bottom of it shall be a cubit round about. And the steps of it shall look toward the east.", "anderson": "", "haweis": "", "noyes": "And the ledge shall be fourteen cubits long by fourteen broad on the four sides thereof; and the border about it shall be half a cubit; and the bottom thereof shall be a cubit round about; and its steps shall look toward the east.", "webster": "And the settle [shall be] fourteen [cubits] long and fourteen broad in its four squares; and the border about it [shall be] half a cubit; and the bottom of it [shall be] a cubit about; and its stairs shall look towards the east.", "vulgate": "et crepido quattuordecim cubitorum longitudinis per quattuordecim latitudinis in quattuor angulis eius et corona in circuitu eius dimidii cubitus et sinus eius unius cubiti per circuitum gradus autem eius versi ad orientem;", "brenton": "And the mercy-seat shall be fourteen cubits in length, by fourteen cubits in breadth on its four sides; and there shall be a border to it carried round about it of half a cubit; and the rim of it shall be a cubit round about; and the steps thereof looking eastward."}}, {"v": 18, "ref": "43:18", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י בֶּן אָדָם֙ כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה אֵ֚לֶּה חֻקּ֣וֹת הַ/מִּזְבֵּ֔חַ בְּ/י֖וֹם הֵעָֽשׂוֹת֑/וֹ לְ/הַעֲל֤וֹת עָלָי/ו֙ עוֹלָ֔ה וְ/לִ/זְרֹ֥ק עָלָ֖י/ו דָּֽם", "en": {"kjv": "And he said unto me, Son of man, thus saith the Lord God; These are the ordinances of the altar in the day when they shall make it, to offer burnt offerings thereon, and to sprinkle blood thereon.", "web": "He said to me, Son of man, thus says the Lord Yahweh: These are the ordinances of the altar in the day when they shall make it, to offer burnt offerings on it, and to sprinkle blood on it.", "bsb": "Then He said to me: “Son of man, this is what the Lord GOD says: ‘These are the statutes for the altar on the day it is constructed, so that burnt offerings may be sacrificed on it and blood may be sprinkled on it:", "asv": "And he said unto me, Son of man, thus saith the Lord Jehovah: These are the ordinances of the altar in the day when they shall make it, to offer burnt-offerings thereon, and to sprinkle blood thereon.", "ylt": "And He saith unto me, `Son of man, Thus said the Lord Jehovah: These are statutes of the altar in the day of its being made to cause burnt-offering to go up on it, and to sprinkle on it blood.", "dra": "And he said to me: Son of man, thus saith the Lord God: These are the ceremonies of the altar, in what day soever it shall be made: that holocausts may be offered upon it, and blood poured out.", "bbe": "And he said to me, Son of man, the Lord God has said, These are the rules for the altar, when they make it, for the offering of burned offerings on it and the draining out of the blood.", "geneva": "And he said vnto me, Sone of man, thus saith ye Lord God, These are ye ordinances of ye altar in the day when they shall make it to offer the burnt offring thereon, and to sprinkle blood thereon.", "wycliffe": "And he seide to me, Thou, sone of man, the Lord God seith these thingis, These ben the customs of the auter, in what euer dai it is maad, that me offre on it brent sacrifice, and blood be sched out.", "rotherham": "Then said he unto me, Son of man, Thus saith My Lord, Yahweh, These, shall be the statutes of the altar, in the day when it is made,—for offering up thereon—an ascending-sacrifice, and for dashing thereon—blood.", "darby": "And he said unto me, Son of man, thus saith the Lord Jehovah: These are the ordinances of the altar in the day when they shall make it, to offer up burnt-offerings thereon, and to sprinkle blood thereon.", "twenty": "", "jps": "And He said unto me: 'Son of man, thus saith the L-rd GOD: These are the ordinances of the altar in the day when they shall make it, to offer burnt-offerings thereon, and to dash blood against it.", "acv": "And he said to me, Son of man, thus says the lord Jehovah: These are the ordinances of the altar in the day when they shall make it, to offer burnt offerings on it, and to sprinkle blood on it.", "anderson": "", "haweis": "", "noyes": "And he said to me, Son of man, thus saith the Lord Jehovah: These are the statutes of the altar, in the day when it is made, to offer burnt-offerings thereon, and to sprinkle blood thereon.", "webster": "And he said to me, Son of man, thus saith the Lord GOD; These [are] the ordinances of the altar in the day when they shall make it, to offer burnt-offerings upon it, and to sprinkle blood upon it.", "vulgate": "et dixit ad me fili hominis haec dicit Dominus Deus hii sunt ritus altaris in quacumque die fuerit fabricatum ut offeratur super illud holocaustum et effundatur sanguis;", "brenton": "And he said to me, Son of man, thus saith the Lord God of Israel; These are the ordinances of the altar in the day of its being made, to offer upon it whole-burnt-offerings, and to pour blood upon it."}}, {"v": 19, "ref": "43:19", "o": "וְ/נָתַתָּ֣ה אֶל הַ/כֹּהֲנִ֣ים הַ/לְוִיִּ֡ם אֲשֶׁ֣ר הֵם֩ מִ/זֶּ֨רַע צָד֜וֹק הַ/קְּרֹבִ֣ים אֵלַ֗/י נְאֻ֛ם אֲדֹנָ֥/י יְהוִ֖ה לְ/שָֽׁרְתֵ֑/נִי פַּ֥ר בֶּן בָּקָ֖ר לְ/חַטָּֽאת", "en": {"kjv": "And thou shalt give to the priests the Levites that be of the seed of Zadok, which approach unto me, to minister unto me, saith the Lord God, a young bullock for a sin offering.", "web": "You shall give to the priests the Levites who are of the seed of Zadok, who are near to me, to minister to me, says the Lord Yahweh, a young bull for a sin offering.", "bsb": "You are to give a young bull from the herd as a sin offering to the Levitical priests who are of the family of Zadok, who approach Me to minister before Me, declares the Lord GOD.", "asv": "Thou shalt give to the priests the Levites that are of the seed of Zadok, who are near unto me, to minister unto me, saith the Lord Jehovah, a young bullock for a sin-offering.", "ylt": "And thou hast given unto the priests, the Levites, who are of the seed of Zadok--who are near unto Me, an affirmation of the Lord Jehovah, to serve Me--a calf from the herd, for a sin-offering.", "dra": "And thou shalt give to the priests, and the Levites, that are of the race of Sadoc, who approach to me, saith the Lord God, to offer to me a calf of the herd for sin.", "bbe": "You are to give to the priests, the Levites of the seed of Zadok, who come near to me, says the Lord God, to do my work, a young ox for a sin-offering.", "geneva": "And thou shalt giue to the Priestes, and to the Leuites, that be of the seede of Zadok, which approch vnto me, to minister vnto me, saith the Lord God, a yong bullocke for a sinne offring.", "wycliffe": "And thou schalt yyue to preestis and dekenes, that ben of the seed of Sadoch, that neiyen to me, seith the Lord God, that thei offre to me a calf of the drooue for synne.", "rotherham": "So then thou shalt give unto the priests the Levites those who are of the seed of Zadok who approach unto me Declareth My Lord Yahweh. to wait upon me—a young bullock as a sin-bearer,", "darby": "And thou shalt give to the priests the Levites that are of the seed of Zadok, who come near unto me, to minister unto me, saith the Lord Jehovah, a young bullock for a sin-offering.", "twenty": "", "jps": "Thou shalt give to the priests the Levites that are of the seed of Zadok, who are near unto Me, to minister unto Me, saith the L-rd GOD, a young bullock for a sin-offering.", "acv": "Thou shall give to the priests the Levites who are of the seed of Zadok, who are near to me, to minister to me, says the lord Jehovah, a young bullock for a sin offering.", "anderson": "", "haweis": "", "noyes": "To the priests, the sons of Levi, of the race of Zadok, that come near to me, saith the Lord Jehovah, to minister to me, thou shalt give a young bullock for a sin-offering.", "webster": "And thou shalt give to the priests the Levites that are of the seed of Zadok, who approach to me, to minister to me, saith the Lord GOD, a young bullock for a sin-offering.", "vulgate": "et dabis sacerdotibus Levitis qui sunt de semine Sadoc qui accedunt ad me ait Dominus Deus ut offerant mihi vitulum de armento pro peccato;", "brenton": "And thou shalt appoint to the priests the Levites of the seed of Sadduc, that draw nigh to me, saith the Lord God, to minister to me, a calf of the herd for a sin-offering."}}, {"v": 20, "ref": "43:20", "o": "וְ/לָקַחְתָּ֣ מִ/דָּמ֗/וֹ וְ/נָ֨תַתָּ֜ה עַל אַרְבַּ֤ע קַרְנֹתָי/ו֙ וְ/אֶל אַרְבַּע֙ פִּנּ֣וֹת הָ/עֲזָרָ֔ה וְ/אֶֽל הַ/גְּב֖וּל סָבִ֑יב וְ/חִטֵּאתָ֥ אוֹת֖/וֹ וְ/כִפַּרְתָּֽ/הוּ", "en": {"kjv": "And thou shalt take of the blood thereof, and put it on the four horns of it, and on the four corners of the settle, and upon the border round about: thus shalt thou cleanse and purge it.", "web": "You shall take of its blood, and put it on the four horns of it, and on the four corners of the ledge, and on the border all around: thus you shall cleanse it and make atonement for it.", "bsb": "You are to take some of its blood and put it on the four horns of the altar, on the four corners of the ledge, and all around the rim; thus you will cleanse the altar and make atonement for it.", "asv": "And thou shalt take of the blood thereof, and put it on the four horns of it, and on the four corners of the ledge, and upon the border round about: thus shalt thou cleanse it and make atonement for it.", "ylt": "And thou hast taken of its blood, and hast put it on its four horns, and on the four corners of its border, and on the border round about, and hast cleansed it, and purified it.", "dra": "And thou shalt take of his blood, and shalt put it upon the four horns thereof, and upon the four corners of the brim, and upon the crown round about: and thou shalt cleanse, and expiate it.", "bbe": "You are to take some of its blood and put it on the four horns and on the four angles of the shelf and on the edge all round: and you are to make it clean and free from sin.", "geneva": "And thou shalt take of the blood thereof, and put it on the foure hornes of it, and on the foure corners of the frame, and vpon the border round about: thus shalt thou clense it, and reconcile it.", "wycliffe": "And thou schalt take of the blood therof, and schalt putte on foure hornes therof, and on foure corneris of heiythe, and on the coroun in cumpas; and thou schalt clense it, and make clene.", "rotherham": "Then shalt thou take of the blood thereof and place upon the four horns thereof and on the four corners of the ledge, and on the boundary, round about,—and shalt cleanse it from sin and put a propitiatory-covering over it.", "darby": "And thou shalt take of its blood, and put it on the four horns thereof, and on the four corners of the settle, and upon the border round about: so shalt thou purge and make atonement for it.", "twenty": "", "jps": "And thou shalt take of the blood thereof, and put it on the four horns of it, and on the four corners of the settle, and upon the border round about; thus shalt thou purify it and make atonement for it.", "acv": "And thou shall take of the blood of it, and put it on the four horns of it, and on the four corners of the ledge, and upon the border round about. Thus thou shall cleanse it and make atonement for it.", "anderson": "", "haweis": "", "noyes": "And thou shalt take of the blood thereof, and put it on its four horns, and on the four corners of the ledge, and on the border round about, and thus cleanse and purge it.", "webster": "And thou shalt take of his blood, and put [it] on the four horns of it, and on the four corners of the settle, and upon the border around: thus shalt thou cleanse and purge it.", "vulgate": "et adsumens de sanguine eius pones super quattuor cornua eius et super quattuor angulos crepidinis et super coronam in circuitu et mundabis illud et expiabis;", "brenton": "And they shall take of its blood, and shall put it on the four horns of the altar, and upon the four corners of the propitiatory, and upon the base round about, and they shall make atonement for it."}}, {"v": 21, "ref": "43:21", "o": "וְ/לָ֣קַחְתָּ֔ אֵ֖ת הַ/פָּ֣ר הַֽ/חַטָּ֑את וּ/שְׂרָפ/וֹ֙ בְּ/מִפְקַ֣ד הַ/בַּ֔יִת מִ/ח֖וּץ לַ/מִּקְדָּֽשׁ", "en": {"kjv": "Thou shalt take the bullock also of the sin offering, and he shall burn it in the appointed place of the house, without the sanctuary.", "web": "You shall also take the bull of the sin offering, and it shall be burnt in the appointed place of the house, outside of the sanctuary.", "bsb": "Then you are to take away the bull for the sin offering and burn it in the appointed part of the temple area outside the sanctuary.", "asv": "Thou shalt also take the bullock of the sin-offering, and it shall be burnt in the appointed place of the house, without the sanctuary.", "ylt": "And thou hast taken the bullock of the sin-offering, and hast burnt it in the appointed place of the house at the outside of the sanctuary.", "dra": "And thou shalt take the calf, that is offered for sin: and thou shalt burn him in a separate place of the house without the sanctuary.", "bbe": "And you are to take the ox of the sin-offering, and have it burned in the special place ordered for it in the house, outside the holy place.", "geneva": "Thou shalt take the bullocke also of the sinne offring, and burne it in the appointed place of the house without the Sanctuarie.", "wycliffe": "And thou schalt take the calf which is offrid for synne, and thou schalt brenne it in a departid place of the hous, with out the seyntuarie.", "rotherham": "Then shalt thou take the bullock bearing sin,- and shalt burn it in the appointed place of the house, outside the sanctuary,", "darby": "And thou shalt take the bullock of the sin-offering, and it shall be burned in the appointed place of the house, outside the sanctuary.", "twenty": "", "jps": "Thou shalt also take the bullock of the sin-offering, and it shall be burnt in the appointed place of the house, without the sanctuary.", "acv": "Thou shall also take the bullock of the sin offering, and it shall be burnt in the appointed place of the house, outside the sanctuary.", "anderson": "", "haweis": "", "noyes": "And thou shalt take the bullock of the sin-offering, and it shall be burned in the appointed place of the house, without the sanctuary.", "webster": "Thou shalt take the bullock also of the sin-offering, and he shall burn it in the appointed place of the house, without the sanctuary.", "vulgate": "et tolles vitulum qui oblatus fuerit pro peccato et conbures illum in separato loco domus extra sanctuarium;", "brenton": "And they shall take the calf of the sin-offering, and it shall be consumed by fire in the separate place of the house, outside the sanctuary."}}, {"v": 22, "ref": "43:22", "o": "וּ/בַ/יּוֹם֙ הַ/שֵּׁנִ֔י תַּקְרִ֛יב שְׂעִיר עִזִּ֥ים תָּמִ֖ים לְ/חַטָּ֑את וְ/חִטְּאוּ֙ אֶת הַ/מִּזְבֵּ֔חַ כַּ/אֲשֶׁ֥ר חִטְּא֖וּ בַּ/פָּֽר", "en": {"kjv": "And on the second day thou shalt offer a kid of the goats without blemish for a sin offering; and they shall cleanse the altar, as they did cleanse it with the bullock.", "web": "On the second day you shall offer a male goat without defect for a sin offering; and they shall cleanse the altar, as they cleansed it with the bull.", "bsb": "On the second day you are to present an unblemished male goat as a sin offering, and the altar is to be cleansed as it was with the bull.", "asv": "And on the second day thou shalt offer a he-goat without blemish for a sin-offering; and they shall cleanse the altar, as they did cleanse it with the bullock.", "ylt": "And on the second day thou dost bring near a kid of the goats, a perfect one, for a sin-offering, and they have cleansed the altar, as they cleansed it for the bullock.", "dra": "And in the second day thou shalt offer a he goat without blemish for sin: and they shall expiate the altar, as they expiated it with the calf.", "bbe": "And on the second day you are to have a he-goat without any mark on it offered for a sin-offering; and they are to make the altar clean as they did with the young ox.", "geneva": "But the second day thou shalt offer an hee goat without blemish for a sinne offring, and they shall clense ye altar, as they did clense it with the bullocke.", "wycliffe": "And in the secounde dai thou schalt offre a buk of geet, which is with out wem, for synne; and thei schulen clense the auter, as thei clensiden in the calf.", "rotherham": "And on the second day, shalt thou bring near a kid of the goats without defect as a sin-bearer,—and they shall cleanse the altar from sin just as they cleansed it from sin with the bullock,", "darby": "And on the second day thou shalt present a he-goat without blemish for a sin-offering; and they shall purge the altar, as they purged it with the bullock.", "twenty": "", "jps": "And on the second day thou shalt offer a he-goat without blemish for a sin-offering; and they shall purify the altar, as they did purify it with the bullock.", "acv": "And on the second day thou shall offer a he-goat without blemish for a sin offering. And they shall cleanse the altar, as they cleansed it with the bullock.", "anderson": "", "haweis": "", "noyes": "And on the second day thou shalt offer a he-goat without blemish for a sin-offering; and they shall cleanse the altar, as they cleansed it with the bullock.", "webster": "And on the second day thou shalt offer a kid of the goats without blemish for a sin-offering; and they shall cleanse the altar, as they cleansed [it] with the bullock.", "vulgate": "et in die secunda offeres hircum caprarum inmaculatum pro peccato et expiabunt altare sicut expiaverunt in vitulo;", "brenton": "And on the second day they shall take two kids of the goats without blemish for a sin-offering; and they shall make atonement for the altar, as they made atonement with the calf."}}, {"v": 23, "ref": "43:23", "o": "בְּ/כַלּוֹתְ/ךָ֖ מֵֽ/חַטֵּ֑א תַּקְרִיב֙ פַּ֣ר בֶּן בָּקָ֣ר תָּמִ֔ים וְ/אַ֥יִל מִן הַ/צֹּ֖אן תָּמִֽים", "en": {"kjv": "When thou hast made an end of cleansing it, thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.", "web": "When you have finished cleansing it, you shall offer a young bull without defect, and a ram out of the flock without defect.", "bsb": "When you have finished the purification, you are to present a young, unblemished bull and an unblemished ram from the flock.", "asv": "When thou hast made an end of cleansing it, thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.", "ylt": "In thy finishing cleansing, thou dost bring near a calf, a son of the herd, a perfect one, and a ram out of the flock, a perfect one.", "dra": "And when thou shalt have made an end of the expiation thereof, thou shalt offer a calf of the herd without blemish, and a ram of the flock without blemish.", "bbe": "And after you have made it clean, let a young ox without a mark be offered, and a male sheep from the flock without a mark.", "geneva": "When thou hast made an ende of clensing it, thou shalt offer a yong bullocke without blemish, and a ram out of the flocke without blemish.", "wycliffe": "And whanne thou hast fillid that clensyng, thou schalt offre a calf of the drooue, which calf is without wem, and a wether with out wem of the floc.", "rotherham": "When thou hast made an end of cleansing from sin, thou shalt bring near a young bullock without defect, and a ram out of the flock without defect;", "darby": "When thou hast ended purging it, thou shalt present a young bullock without blemish, and a ram out of the flock without blemish;", "twenty": "", "jps": "When thou hast made an end of purifying it, thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.", "acv": "When thou have made an end of cleansing it, thou shall offer a young bullock without blemish, and a ram out of the flock without blemish.", "anderson": "", "haweis": "", "noyes": "And when thou hast made an end of cleansing it, thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.", "webster": "When thou hast made an end of cleansing [it], thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.", "vulgate": "cumque conpleveris expians illud offeres vitulum de armento inmaculatum et arietem de grege inmaculatum;", "brenton": "And after they have finished the atonement, they shall bring an unblemished calf of the herd, and an unblemished ram of the flock."}}, {"v": 24, "ref": "43:24", "o": "וְ/הִקְרַבְתָּ֖/ם לִ/פְנֵ֣י יְהוָ֑ה וְ/הִשְׁלִ֨יכוּ הַ/כֹּהֲנִ֤ים עֲלֵי/הֶם֙ מֶ֔לַח וְ/הֶעֱל֥וּ אוֹתָ֛/ם עֹלָ֖ה לַֽ/יהוָֽה", "en": {"kjv": "And thou shalt offer them before the Lord, and the priests shall cast salt upon them, and they shall offer them up for a burnt offering unto the Lord.", "web": "You shall bring them near to Yahweh, and the priests shall cast salt on them, and they shall offer them up for a burnt offering to Yahweh.", "bsb": "You must present them before the LORD; the priests are to sprinkle salt on them and sacrifice them as a burnt offering to the LORD.", "asv": "And thou shalt bring them near before Jehovah, and the priests shall cast salt upon them, and they shall offer them up for a burnt-offering unto Jehovah.", "ylt": "And thou hast brought them near before Jehovah, and the priests have cast upon them salt, and have caused them to go up, a burnt-offering to Jehovah.", "dra": "And thou shalt offer them in the sight of the Lord, and the priests shall put salt upon them, and shall offer them a holocaust to the Lord.", "bbe": "And you are to take them before the Lord, and the priests will put salt on them, offering them up for a burned offering to the Lord.", "geneva": "And thou shalt offer them before ye Lord, and the Priestes shall cast salt vpon them, and they shall offer them for a burnt offring vnto ye Lord.", "wycliffe": "And thou schalt offre tho in the siyt of the Lord; and prestis schulen putte salt on tho, and schulen offre tho in to brent sacrifice to the Lord.", "rotherham": "and shalt bring them near before Yahweh,—and the priests shall cast over them salt, so shall they cause them to go up as an ascending-sacrifice to Yahweh.", "darby": "and thou shalt present them before Jehovah; and the priests shall cast salt upon them, and they shall offer them up for a burnt-offering unto Jehovah.", "twenty": "", "jps": "And thou shalt present them before HaShem, and the priests shall cast salt upon them, and they shall offer them up for a burnt-offering unto HaShem.", "acv": "And thou shall bring them near before Jehovah, and the priests shall cast salt upon them, and they shall offer them up for a burnt offering to Jehovah.", "anderson": "", "haweis": "", "noyes": "And thou shalt offer them before Jehovah, and the priests shall cast salt upon them, and offer them up for a burnt-offering to Jehovah.", "webster": "And thou shalt offer them before the LORD, and the priests shall cast salt upon them, and they shall offer them [for] a burnt-offering to the LORD.", "vulgate": "et offeres eos in conspectu Domini et mittent sacerdotes super eos sal et offerent eos holocaustum Domino;", "brenton": "And ye shall offer them before the Lord, and the priests shall sprinkle salt upon them, and shall offer them up as whole-burnt-offerings to the Lord."}}, {"v": 25, "ref": "43:25", "o": "שִׁבְעַ֣ת יָמִ֔ים תַּעֲשֶׂ֥ה שְׂעִיר חַטָּ֖את לַ/יּ֑וֹם וּ/פַ֧ר בֶּן בָּקָ֛ר וְ/אַ֥יִל מִן הַ/צֹּ֖אן תְּמִימִ֥ים יַעֲשֽׂוּ", "en": {"kjv": "Seven days shalt thou prepare every day a goat for a sin offering: they shall also prepare a young bullock, and a ram out of the flock, without blemish.", "web": "Seven days you shall prepare every day a goat for a sin offering: they shall also prepare a young bull, and a ram out of the flock, without defect.", "bsb": "For seven days you are to provide a male goat daily for a sin offering; you are also to provide a young bull and a ram from the flock, both unblemished.", "asv": "Seven days shalt thou prepare every day a goat for a sin-offering: they shall also prepare a young bullock, and a ram out of the flock, without blemish.", "ylt": "Seven days thou dost prepare a goat for a sin-offering daily, and a bullock, a son of the herd, and a ram out of the flock, perfect ones, do they prepare.", "dra": "Seven days shalt thou offer a he goat for sin daily: they shall offer also a calf of the herd, and a ram of the flock without blemish.", "bbe": "Every day for seven days you are to give a goat for a sin-offering: and let them give in addition a young ox and a male sheep from the flock without any mark on them.", "geneva": "Seuen dayes shalt thou prepare euery day an hee goate for a sinne offring: they shall also prepare a yong bullocke and a ramme out of the flocke, without blemish.", "wycliffe": "Bi seuene daies thou schalt make a buk of geet for synne, ech dai; and thei schulen offre a calf of the drooue, and a wether vnwemmed of scheep.", "rotherham": "Seven days, shalt thou offer a sin-bearing goat for each day,—and a young bullock and aram out of the flock without defect, shall they offer.", "darby": "Seven days shalt thou offer daily a goat for a sin-offering; they shall also offer a young bullock, and a ram out of the flock without blemish.", "twenty": "", "jps": "Seven days shalt thou prepare every day a goat for a sin-offering; they shall also prepare a young bullock, and a ram out of the flock, without blemish.", "acv": "Seven days thou shall prepare each day a goat for a sin offering. They shall also prepare a young bullock, and a ram out of the flock, without blemish.", "anderson": "", "haweis": "", "noyes": "Seven days shalt thou sacrifice daily a goat for a sin-offering; they shall also sacrifice a young bullock, and a ram out of the flock without blemish.", "webster": "Seven days shalt thou prepare every day a goat [for] a sin-offering: they shall also prepare a young bullock, and a ram out of the flock, without blemish.", "vulgate": "septem diebus facies hircum pro peccato cotidie et vitulum de armento et arietem de pecoribus inmaculatos offerent;", "brenton": "Seven days shalt thou offer a kid daily for a sin-offering, and a calf of the herd, and a ram out of the flock: they shall sacrifice them unblemished for seven days:"}}, {"v": 26, "ref": "43:26", "o": "שִׁבְעַ֣ת יָמִ֗ים יְכַפְּרוּ֙ אֶת הַ/מִּזְבֵּ֔חַ וְ/טִֽהֲר֖וּ אֹת֑/וֹ וּ/מִלְא֖וּ יד/ו יָדָֽי/ו", "en": {"kjv": "Seven days shall they purge the altar and purify it; and they shall consecrate themselves.", "web": "Seven days shall they make atonement for the altar and purify it; so shall they consecrate it.", "bsb": "For seven days the priests are to make atonement for the altar and cleanse it; so they shall consecrate it.", "asv": "Seven days shall they make atonement for the altar and purify it; so shall they consecrate it.", "ylt": "Seven days they purify the altar, and have cleansed it, and filled their hand.", "dra": "Seven days shall they expiate the altar, and shall cleanse it: and they shall consecrate it.", "bbe": "For seven days they are to make offerings to take away sin from the altar and to make it clean; so they are to make it holy.", "geneva": "Thus shall they seuen dayes purifie the altar, and clense it, and consecrate it.", "wycliffe": "Bi seuene daies thei schulen clense the auter, and schulen make it cleene, and thei schulen fille the hond therof.", "rotherham": "Seven days, shall they put a propitiatory covering over the altar, and shall purify it,—and shall consecrate it.", "darby": "Seven days shall they make atonement for the altar and purify it, and consecrate it.", "twenty": "", "jps": "Seven days shall they make atonement for the altar and cleanse it; so shall they consecrate it.", "acv": "Seven days they shall make atonement for the altar and purify it. So they shall consecrate it.", "anderson": "", "haweis": "", "noyes": "Seven days shall they purge the altar, and purify it, and consecrate themselves.", "webster": "Seven days shall they purge the altar and purify it; and they shall consecrate themselves.", "vulgate": "septem diebus expiabunt altare et mundabunt illud et implebunt manum eius;", "brenton": "and they shall make atonement for the altar, and shall purge it; and they shall consecrate themselves."}}, {"v": 27, "ref": "43:27", "o": "וִֽ/יכַלּ֖וּ אֶת הַ/יָּמִ֑ים וְ/הָיָה֩ בַ/יּ֨וֹם הַ/שְּׁמִינִ֜י וָ/הָ֗לְאָה יַעֲשׂ֨וּ הַ/כֹּהֲנִ֤ים עַל הַ/מִּזְבֵּ֨חַ֙ אֶת עוֹלֽוֹתֵי/כֶם֙ וְ/אֶת שַׁלְמֵי/כֶ֔ם וְ/רָצִ֣אתִי אֶתְ/כֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהֹוִֽה", "en": {"kjv": "And when these days are expired, it shall be, that upon the eighth day, and so forward, the priests shall make your burnt offerings upon the altar, and your peace offerings; and I will accept you, saith the Lord God.", "web": "When they have accomplished the days, it shall be that on the eighth day, and forward, the priests shall make your burnt offerings on the altar, and your peace offerings; and I will accept you, says the Lord Yahweh.", "bsb": "At the end of these days, from the eighth day on, the priests are to present your burnt offerings and peace offerings on the altar. Then I will accept you, declares the Lord GOD.’”", "asv": "And when they have accomplished the days, it shall be that upon the eighth day, and forward, the priests shall make your burnt-offerings upon the altar, and your peace-offerings; and I will accept you, saith the Lord Jehovah.", "ylt": "And the days are completed, and it hath come to pass on the eighth day, and henceforth, the priests prepare on the altar your burnt-offerings and your peace-offerings, and I have accepted you--an affirmation of the Lord Jehovah.'", "dra": "And the days being expired, on the eighth day and thenceforward, the priests shall offer your holocausts upon the altar, and the peace offerings: and I will be pacified towards you, saith the Lord God.", "bbe": "And when these days have come to an end, then on the eighth day and after, the priests will make your burned offerings on the altar and your peace-offerings; and I will take pleasure in you, says the Lord.", "geneva": "And when these dayes are expired, vpon the eight day and so forth, the Priests shall make your burnt offrings vpon the altar, and your peace offrings, and I will accept you, saith the Lord God.", "wycliffe": "Forsothe whanne seuene daies ben fillid, in the eiythe dai and ferther prestis schulen make on the auter youre brent sacrifices, and tho thingis whiche thei offren for pees; and Y schal be plesid to you, seith the Lord God.", "rotherham": "When the days shall be accomplished, then shall it be on the eighth day and forward, that the priests shall offer upon the altar your ascending-sacrifices and your peace offerings. And I will accept you Declareth, My Lord Yahweh.", "darby": "And when these days are ended, it shall be that upon the eighth day and onwards the priests shall offer your burnt-offerings upon the altar, and your peace-offerings; and I will accept you, saith the Lord Jehovah.", "twenty": "", "jps": "And when they have accomplished the days, it shall be that upon the eighth day, and forward, the priests shall make your burnt-offerings upon the altar, and your peace-offerings; and I will accept you, saith the L-rd GOD.'", "acv": "And when they have accomplished the days, it shall be that upon the eighth day, and forward, the priests shall make your burnt offerings upon the altar, and your peace offerings. And I will accept you, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And when they have finished these days, it shall be that on the eighth day and forward the priests shall present your burnt-offerings and your thank-offerings upon the altar, and I will accept you, saith the Lord Jehovah.", "webster": "And when these days have expired, it shall be, [that] upon the eighth day, and [so] forward, the priests shall make your burnt-offerings upon the altar, and your peace-offerings: and I will accept you, saith the Lord GOD.", "vulgate": "expletis autem diebus in die octava et ultra facient sacerdotes super altare holocausta vestra et quae pro pace offerunt et placatus ero vobis ait Dominus Deus;", "brenton": "And it shall come to pass from the eighth day and onward, that the priests shall offer your whole-burnt-offerings on the altar, and your peace-offerings; and I will accept you, saith the Lord."}}]}, {"c": 44, "verses": [{"v": 1, "ref": "44:1", "o": "וַ/יָּ֣שֶׁב אֹתִ֗/י דֶּ֣רֶךְ שַׁ֤עַר הַ/מִּקְדָּשׁ֙ הַֽ/חִיצ֔וֹן הַ/פֹּנֶ֖ה קָדִ֑ים וְ/ה֖וּא סָגֽוּר", "en": {"kjv": "Then he brought me back the way of the gate of the outward sanctuary which looketh toward the east; and it was shut.", "web": "Then he brought me back by the way of the outer gate of the sanctuary, which looks toward the east; and it was shut.", "bsb": "The man then brought me back to the outer gate of the sanctuary that faced east, but it was shut.", "asv": "Then he brought me back by the way of the outer gate of the sanctuary, which looketh toward the east; and it was shut.", "ylt": "And he causeth me to turn back the way of the gate of the outer sanctuary that is looking eastward, and it is shut.", "dra": "And he brought me back to the way of the gate of the outward sanctuary, which looked towards the east: and it was shut.", "bbe": "And he took me back to the outer doorway of the holy place, looking to the east; and it was shut.", "geneva": "Then he brought me towarde the gate of the outwarde Sanctuarie, which turneth towarde the East, and it was shut.", "wycliffe": "And he turnede me to the weie of the yate of the outermore seyntuarie, which yate byhelde to the eest, and was closid.", "rotherham": "Then he brought me back toward the outer gate of the sanctuary, which looked toward the east,—but, it was shut.", "darby": "And he brought me back toward the outer gate of the sanctuary which looked toward the east; and it was shut.", "twenty": "", "jps": "Then he brought me back the way of the outer gate of the sanctuary, which looketh toward the east; and it was shut.", "acv": "Then he brought me back by the way of the outer gate of the sanctuary, which looks toward the east. And it was shut.", "anderson": "", "haweis": "", "noyes": "Then he brought me back to the outer gate of the sanctuary, which looketh toward the east; and it was shut.", "webster": "Then he brought me back the way of the gate of the outward sanctuary which looketh towards the east; and it [was] shut.", "vulgate": "et convertit me ad viam portae sanctuarii exterioris quae respiciebat ad orientem et erat clausa;", "brenton": "Then he brought me back by the way of the outer gate of the sanctuary that looks eastward; and it was shut."}}, {"v": 2, "ref": "44:2", "o": "וַ/יֹּ֨אמֶר אֵלַ֜/י יְהוָ֗ה הַ/שַּׁ֣עַר הַ/זֶּה֩ סָג֨וּר יִהְיֶ֜ה לֹ֣א יִפָּתֵ֗חַ וְ/אִישׁ֙ לֹא יָ֣בֹא ב֔/וֹ כִּ֛י יְהוָ֥ה אֱלֹהֵֽי יִשְׂרָאֵ֖ל בָּ֣א ב֑/וֹ וְ/הָיָ֖ה סָגֽוּר", "en": {"kjv": "Then said the Lord unto me; This gate shall be shut, it shall not be opened, and no man shall enter in by it; because the Lord, the God of Israel, hath entered in by it, therefore it shall be shut.", "web": "Yahweh said to me, This gate shall be shut; it shall not be opened, neither shall any man enter in by it; for Yahweh, the God of Israel, has entered in by it; therefore it shall be shut.", "bsb": "And the LORD said to me, “This gate is to remain shut. It shall not be opened, and no man shall enter through it, because the LORD, the God of Israel, has entered through it. Therefore it will remain shut.", "asv": "And Jehovah said unto me, This gate shall be shut; it shall not be opened, neither shall any man enter in by it; for Jehovah, the God of Israel, hath entered in by it; therefore it shall be shut.", "ylt": "And Jehovah saith unto me, `This gate is shut, it is not opened, and none doth go in by it, for Jehovah, God of Israel, hath come in by it, and it hath been shut.", "dra": "And the Lord said to me: This gate shall be shut, it shall not be opened, and no man shall pass through it: because the Lord the God of Israel hath entered in by it, and it shall be shut", "bbe": "And the Lord said to me, This doorway is to be shut, it is not to be open, and no man is to go in by it, because the Lord, the God of Israel, has gone in by it; and it is to be shut.", "geneva": "Then saide the Lord vnto me, This gate shalbe shut, and shall not bee opened, and no man shall enter by it, because the Lord God of Israel hath entred by it, and it shalbe shut.", "wycliffe": "And the Lord seide to me, This yate schal be closid, and schal not be opened, and a man schal not passe thorou it; for the Lord God of Israel entride bi it, and it schal be closid to the prince.", "rotherham": "Then said Yahweh unto me This gate shut, shall remain It shall not be opened And no man shall enter thereby, Because Yahweh, God of Israel, doth enter thereby,- Therefore shall it remain—shut.", "darby": "And Jehovah said unto me, This gate shall be shut; it shall not be opened, and no one shall enter in by it: for Jehovah, theGod of Israel, hath entered in by it; and it shall be shut.", "twenty": "", "jps": "And HaShem said unto me: 'This gate shall be shut, it shall not be opened, neither shall any man enter in by it, for HaShem, the G-d of Israel, hath entered in by it; therefore it shall be shut.", "acv": "And Jehovah said to me, This gate shall be shut. It shall not be opened, nor shall any man enter in by it, for Jehovah, the God of Israel, has entered in by it. Therefore it shall be shut.", "anderson": "", "haweis": "", "noyes": "Then said Jehovah to me: This gate shall be shut; it shall not be opened, and no man shall enter in by it; because Jehovah, the God of Israel, entered in by it, therefore it shall be shut.", "webster": "Then said the LORD to me; This gate shall be shut, it shall not be opened, and no man shall enter in by it; because the LORD the God of Israel hath entered in by it, therefore it shall be shut.", "vulgate": "et dixit Dominus ad me porta haec clausa erit non aperietur et vir non transiet per eam quoniam Dominus Deus Israhel ingressus est per eam eritque clausa;", "brenton": "And the Lord said to me, This gate shall be shut, it shall not be opened, and no one shall pass through it; for the Lord God of Israel shall enter by it, and it shall be shut."}}, {"v": 3, "ref": "44:3", "o": "אֶֽת הַ/נָּשִׂ֗יא נָ֥שִׂיא ה֛וּא יֵֽשֶׁב בּ֥/וֹ לֶ/אֱכָול לֶ֖חֶם לִ/פְנֵ֣י יְהוָ֑ה מִ/דֶּ֨רֶךְ אֻלָ֤ם הַ/שַּׁ֨עַר֙ יָב֔וֹא וּ/מִ/דַּרְכּ֖/וֹ יֵצֵֽא", "en": {"kjv": "It is for the prince; the prince, he shall sit in it to eat bread before the Lord; he shall enter by the way of the porch of that gate, and shall go out by the way of the same.", "web": "As for the prince, he shall sit therein as prince to eat bread before Yahweh; he shall enter by the way of the porch of the gate, and shall go out by the way of the same.", "bsb": "Only the prince himself may sit inside the gateway to eat in the presence of the LORD. He must enter by way of the portico of the gateway and go out the same way.”", "asv": "As for the prince, he shall sit therein as prince to eat bread before Jehovah; he shall enter by the way of the porch of the gate, and shall go out by the way of the same.", "ylt": "The prince, who is prince, he sitteth by it to eat bread before Jehovah, by the way of the porch of the gate he cometh in, and by its way he goeth out.'", "dra": "For the prince. The prince himself shall sit in it, to eat bread before the Lord: he shall enter in by the way of the porch of the gate, and shall go out by the same way.", "bbe": "But the ruler will be seated there to take his food before the Lord; he will go in by the covered way to the door, and will come out by the same way.", "geneva": "It appertaineth to the Prince: the Prince himselfe shall sit in it to eate bread before the Lord: he shall enter by the way of the porche of that gate, and shall go out by the way of the same.", "wycliffe": "The prince hym silf schal sitte ther ynne, that he ete breed bifor the Lord; he schal go yn bi the weie of the yate of the porche, and he schal go out bi the weie therof.", "rotherham": "The prince! as prince, he, shall sit therein, To eat food before Yahweh,— By way of the porch of the gate, shall he go in, and By way thereof, shall he come out.", "darby": "As for the prince, he, the prince, shall sit in it to eat bread before Jehovah: he shall enter by the way of the porch of the gate, and shall go out by the way of the same.", "twenty": "", "jps": "As for the prince, being a prince, he shall sit therein to eat bread before HaShem; he shall enter by the way of the porch of the gate, and shall go out by the way of the same.'", "acv": "As for the ruler, he shall sit in it as ruler to eat bread before Jehovah. He shall enter by the way of the porch of the gate, and shall go out by the way of the same.", "anderson": "", "haweis": "", "noyes": "The prince, because he is prince, shall sit in it, to eat food before Jehovah; he shall enter through the porch of that gate, and by the same way shall he go out.", "webster": "[It is] for the prince; the prince, he shall sit in it to eat bread before the LORD; he shall enter by the way of the porch of [that] gate, and shall go out by the way of the same.", "vulgate": "principi princeps ipse sedebit in ea ut comedat panem coram Domino per viam vestibuli portae ingredietur et per viam eius egredietur;", "brenton": "For the prince, he shall sit in it, to eat bread before the Lord; he shall go in by the way of the porch of the gate, and shall go forth by the way of the same."}}, {"v": 4, "ref": "44:4", "o": "וַ/יְבִיאֵ֜/נִי דֶּֽרֶךְ שַׁ֣עַר הַ/צָּפוֹן֮ אֶל פְּנֵ֣י הַ/בַּיִת֒ וָ/אֵ֕רֶא וְ/הִנֵּ֛ה מָלֵ֥א כְבוֹד יְהוָ֖ה אֶת בֵּ֣ית יְהוָ֑ה וָ/אֶפֹּ֖ל אֶל פָּנָֽ/י", "en": {"kjv": "Then brought he me the way of the north gate before the house: and I looked, and, behold, the glory of the Lord filled the house of the Lord: and I fell upon my face.", "web": "Then he brought me by the way of the north gate before the house; and I looked, and behold, Yahweh’s glory filled Yahweh’s house: and I fell on my face.", "bsb": "Then the man brought me to the front of the temple by way of the north gate. I looked and saw the glory of the LORD filling His temple, and I fell facedown.", "asv": "Then he brought me by the way of the north gate before the house; and I looked, and, behold, the glory of Jehovah filled the house of Jehovah: and I fell upon my face.", "ylt": "And he bringeth me in the way of the north gate unto the front of the house, and I look, and lo, filled hath the honour of Jehovah the house of Jehovah, and I fall on my face.", "dra": "And he brought me by the way of the north gate, in the sight of the house: and I saw, and behold the glory of the Lord filled the house of the Lord: and I fell on my face.", "bbe": "And he took me to the north doorway in front of the house; and, looking, I saw that the house of the Lord was full of the glory of the Lord; and I went down on my face.", "geneva": "Then brought he mee toward the North gate before the House: and when I looked, beholde, the glorie of the Lord filled the house of the Lord, and I fell vpon my face.", "wycliffe": "And he ledde me bi the weie of the north yate, in the siyt of the hous; and Y siy, and lo! the glorie of the Lord fillide the hous of the Lord; and Y felle doun on my face.", "rotherham": "Then he brought me in by way of the north gate unto the front of the house, and I looked and lo! the glory of Yahweh, filled the house of Yahweh,— so I fell upon my face.", "darby": "And he brought me the way of the north gate before the house; and I beheld, and lo, the glory of Jehovah filled the house of Jehovah: and I fell upon my face.", "twenty": "", "jps": "Then he brought me the way of the north gate before the house; and I looked, and, behold, the glory of HaShem filled the house of HaShem; and I fell upon my face.", "acv": "Then he brought me by the way of the north gate before the house. And I looked, and, behold, the glory of Jehovah filled the house of Jehovah. And I fell upon my face.", "anderson": "", "haweis": "", "noyes": "Then he brought me to the north gate before the house; and I looked, and behold, the glory of Jehovah filled the house of Jehovah. And I fell upon my face.", "webster": "Then he brought me the way of the north gate before the house: and I looked, and behold, the glory of the LORD filled the house of the LORD: and I fell upon my face.", "vulgate": "et adduxit me per viam portae aquilonis in conspectu domus et vidi et ecce implevit gloria Domini domum Domini et cecidi in faciem meam;", "brenton": "And he brought me in by the way of the gate that looks northward, in front of the house: and I looked, and, behold, the house was full of the glory of the Lord: and I fell upon my face."}}, {"v": 5, "ref": "44:5", "o": "וַ/יֹּ֨אמֶר אֵלַ֜/י יְהֹוָ֗ה בֶּן אָדָ֡ם שִׂ֣ים לִבְּ/ךָ֩ וּ/רְאֵ֨ה בְ/עֵינֶ֜י/ךָ וּ/בְ/אָזְנֶ֣י/ךָ שְּׁמָ֗ע אֵ֣ת כָּל אֲשֶׁ֤ר אֲנִי֙ מְדַבֵּ֣ר אֹתָ֔/ךְ לְ/כָל חֻקּ֥וֹת בֵּית יְהוָ֖ה וּ/לְ/כָל תורת/ו תּֽוֹרֹתָ֑י/ו וְ/שַׂמְתָּ֤ לִבְּ/ךָ֙ לִ/מְב֣וֹא הַ/בַּ֔יִת בְּ/כֹ֖ל מוֹצָאֵ֥י הַ/מִּקְדָּֽשׁ", "en": {"kjv": "And the Lord said unto me, Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say unto thee concerning all the ordinances of the house of the Lord, and all the laws thereof; and mark well the entering in of the house, with every going forth of the sanctuary.", "web": "Yahweh said to me, Son of man, mark well, and see with your eyes, and hear with your ears all that I tell you concerning all the ordinances of Yahweh’s house, and all its laws; and mark well the entrance of the house, with every exit of the sanctuary.", "bsb": "The LORD said to me: “Son of man, pay attention; look carefully with your eyes and listen closely with your ears to everything I tell you concerning all the statutes and laws of the house of the LORD. Take careful note of the entrance to the temple, along with all the exits of the sanctuary.", "asv": "And Jehovah said unto me, Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say unto thee concerning all the ordinances of the house of Jehovah, and all the laws thereof; and mark well the entrance of the house, with every egress of the sanctuary.", "ylt": "And Jehovah saith unto me, `Son of man, set thy heart, and see with thine eyes, and with thine ears hear, all that I am speaking with thee, of all the statutes of the house of Jehovah, and of all its laws; and thou hast set thy heart to the entrance of the house, with all the outlets of the sanctuary,", "dra": "And the Lord said to me: Son of man, attend with thy heart and behold with thy eyes, and hear with thy ears, all that I say to thee concerning all the ceremonies of the house of the Lord, and concerning all the laws thereof: and mark well the ways of the temple, with all the goings out of the sanctuary.", "bbe": "And the Lord said to me, Son of man, take to heart, and let your eyes see and your ears be open to everything I say to you about all the rules of the house of the Lord and all its laws; and take note of the ways into the house and all the ways out of the holy place.", "geneva": "And the Lord sayd vnto me, Sonne of man, marke well, and behold with thine eyes, and heare with thine eares, all that I say vnto thee, concerning al the ordinances of the house of the Lord, and al the lawes thereof, and marke well the entring in of the house with euery going forth of the Sanctuarie,", "wycliffe": "And the Lord seide to me, Thou, sone of man, sette thin herte, and se with thin iyen, and here with thin eeris alle thingis whiche Y speke to thee, of al the ceremonyes of the hous of the Lord, and of alle the lawis therof; and thou schalt sette thin herte in the weies of the temple, bi alle the goyngis out of the seyntuarie.", "rotherham": "And Yahweh said unto me, Son of man Apply thy heart And see with thine eyes And with thine ears, hear thou All that I am speaking with thee, As to all the statutes of the house of Yahweh and As to all the laws thereof,- And thou shalt apply thy heart To the entering in of the house, With all the exits of the sanctuary.", "darby": "And Jehovah said unto me, Son of man, apply thy heart, and behold with thine eyes, and hear with thine ears all that I say unto thee concerning all the statutes of the house of Jehovah, and all the laws thereof; and mark well the entering in of the house, with every going forth of the sanctuary;", "twenty": "", "jps": "And HaShem said unto me: 'Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say unto thee concerning all the ordinances of the house of HaShem, and all the laws thereof; and mark well the entering in of the house, with every going forth of the sanctuary.", "acv": "And Jehovah said to me, Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say to thee concerning all the ordinances of the house of Jehovah, and all the laws of it. And mark well the entrance of the house, with every exit of the sanctuary.", "anderson": "", "haweis": "", "noyes": "And Jehovah said to me: Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say to thee concerning all the ordinances of the house of Jehovah, and all the laws thereof; and mark well all the entrances of the house, and all the outward passages of the sanctuary.", "webster": "And the LORD said to me, Son of man mark well, and behold with thy eyes, and hear with thy ears all that I say to thee concerning all the ordinances of the house of the LORD, and all its laws; and mark well the entrance of the house, with every going forth of the sanctuary;", "vulgate": "et dixit ad me Dominus fili hominis pone cor tuum et vide oculis tuis et auribus tuis audi omnia quae ego loquor ad te de universis caerimoniis domus Domini et de cunctis legibus eius et pones cor tuum in viis templi per omnes exitus sanctuarii;", "brenton": "And the Lord said to me, Son of man, attend with thine heart, and see with thine eyes, and hear with thine ears all that I say to thee, according to all the ordinances of the house of the Lord, and all the regulations thereof; and thou shalt attend well to the entrance of the house, according to all its outlets, in all the holy things."}}, {"v": 6, "ref": "44:6", "o": "וְ/אָמַרְתָּ֤ אֶל מֶ֨רִי֙ אֶל בֵּ֣ית יִשְׂרָאֵ֔ל כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה רַב לָ/כֶ֛ם מִֽ/כָּל תּוֹעֲבֽוֹתֵי/כֶ֖ם בֵּ֥ית יִשְׂרָאֵֽל", "en": {"kjv": "And thou shalt say to the rebellious, even to the house of Israel, Thus saith the Lord God; O ye house of Israel, let it suffice you of all your abominations,", "web": "You shall tell the rebellious, even to the house of Israel, Thus says the Lord Yahweh: you house of Israel, let it suffice you of all your abominations,", "bsb": "Tell the rebellious house of Israel that this is what the Lord GOD says: ‘I have had enough of all your abominations, O house of Israel.", "asv": "And thou shalt say to the rebellious, even to the house of Israel, Thus saith the Lord Jehovah: O ye house of Israel, let it suffice you of all your abominations,", "ylt": "and hast said unto the rebellious, unto the house of Israel: Thus said the Lord Jehovah: Enough to you--of all your abominations, O house of Israel.", "dra": "And thou shalt say to the house of Israel that provoketh me: Thus saith the Lord God: Let all your wicked doings suffice you, O house of Israel:", "bbe": "And say to the uncontrolled children of Israel, This is what the Lord has said: O you children of Israel, let it be enough for you, among the disgusting things which you have done,", "geneva": "And thou shalt say to the rebellious, euen to ye house of Israel, Thus saith ye Lord God, O house of Israel, ye haue ynough of al your abominations,", "wycliffe": "And thou schalt seie to the hous of Israel terrynge me to wraththe, The Lord God seith these thingis, Ye hous of Israel, alle youre grete trespassis suffice to you,", "rotherham": "So then thou shalt say unto the perverse [house] unto the house of Israel, Thus saith My Lord, Yahweh: Let it more than suffice you Out of all your abominations, O house of Israel:", "darby": "and say to the rebellious, to the house of Israel, Thus saith the Lord Jehovah: Let it suffice you of all your abominations, O house of Israel,", "twenty": "", "jps": "And thou shalt say to the rebellious, even to the house of Israel: Thus saith the L-rd GOD: O ye house of Israel, let it suffice you of all your abominations,", "acv": "And thou shall say to the rebellious, even to the house of Israel, Thus says the lord Jehovah: O ye house of Israel, let it suffice you of all your abominations,", "anderson": "", "haweis": "", "noyes": "And say to the rebellious house of Israel, Thus saith the Lord Jehovah: Let it suffice you of all your abominations, O house of Israel,", "webster": "And thou shalt say to the rebellious, [even] to the house of Israel, Thus saith the Lord GOD; O ye house of Israel, let it suffice you of all your abominations;", "vulgate": "et dices ad exasperantem me domum Israhel haec dicit Dominus Deus sufficiant vobis omnia scelera vestra domus Israhel;", "brenton": "And thou shalt say to the provoking house, even to the house of Israel, Thus saith the Lord God; Let it suffice you to have committed all your iniquities, O house of Israel!"}}, {"v": 7, "ref": "44:7", "o": "בַּ/הֲבִיאֲ/כֶ֣ם בְּנֵֽי נֵכָ֗ר עַרְלֵי לֵב֙ וְ/עַרְלֵ֣י בָשָׂ֔ר לִ/הְי֥וֹת בְּ/מִקְדָּשִׁ֖/י לְ/חַלְּל֣/וֹ אֶת בֵּיתִ֑/י בְּ/הַקְרִֽיבְ/כֶ֤ם אֶת לַחְמִ/י֙ חֵ֣לֶב וָ/דָ֔ם וַ/יָּפֵ֨רוּ֙ אֶת בְּרִיתִ֔/י אֶ֖ל כָּל תּוֹעֲבוֹתֵי/כֶֽם", "en": {"kjv": "In that ye have brought into my sanctuary strangers, uncircumcised in heart, and uncircumcised in flesh, to be in my sanctuary, to pollute it, even my house, when ye offer my bread, the fat and the blood, and they have broken my covenant because of all your abominations.", "web": "in that you have brought in foreigners, uncircumcised in heart and uncircumcised in flesh, to be in my sanctuary, to profane it, even my house, when you offer my bread, the fat and the blood, and they have broken my covenant, to add to all your abominations.", "bsb": "In addition to all your other abominations, you brought in foreigners uncircumcised in both heart and flesh to occupy My sanctuary; you defiled My temple when you offered My food—the fat and the blood; you broke My covenant.", "asv": "in that ye have brought in foreigners, uncircumcised in heart and uncircumcised in flesh, to be in my sanctuary, to profane it, even my house, when ye offer my bread, the fat and the blood, and they have broken my covenant, to add unto all your abominations.", "ylt": "In your bringing in sons of a stranger, uncircumcised of heart, and uncircumcised of flesh, to be in My sanctuary, to pollute it, even My house, in your bringing near My bread, fat, and blood, and they break My covenant by all your abominations,", "dra": "In that you have brought in strangers uncircumcised in heart, and uncircumcised in flesh, to be in my sanctuary, and to defile my house: and you offer my bread, the fat, and the blood: and you have broken my covenant by all your wicked doings.", "bbe": "To have let men from strange lands, without circumcision of heart or flesh, come into my holy place, making my house unclean; and to have made the offering of my food, even the fat and the blood; and in addition to all your disgusting ways, you have let my agreement be broken.", "geneva": "Seeing that yee haue brought into my Sanctuarie strangers, vncircumcised in heart, and vncircumcised in flesh, to bee in my Sanctuarie, to pollute mine house, when yee offer my bread, euen fat, and blood: and they haue broken my couenant, because of all your abominations.", "wycliffe": "for ye bryngen in alien sones, vncircumcidid in herte, and vncircumcidid in fleisch, that thei be in my seyntuarie, and defoule myn hous. And ye offren my looues, ynnere fatnesse, and blood, and breken my couenaunt in alle youre grete trespassis.", "rotherham": "That ye brought in the sons of the foreigner Uncircumcised in heart and uncircumcised in flesh, To be in my sanctuary. So that he profaned my house,- That ye brought near as my food the fat and the blood, And so they brake my covenant—Among all your abominations;", "darby": "in that ye have brought strangers, uncircumcised in heart and uncircumcised in flesh, to be in my sanctuary, to profane it, [even] my house, when ye offered my bread, the fat and the blood; and they have broken my covenant besides all your abominations.", "twenty": "", "jps": "in that ye have brought in aliens, uncircumcised in heart and uncircumcised in flesh, to be in My sanctuary, to profane it, even My house, when ye offer My bread, the fat and the blood, and they have broken My covenant, to add unto all your abominations.", "acv": "in that ye have brought in foreigners, uncircumcised in heart and uncircumcised in flesh, to be in my sanctuary, to profane it, even my house, when ye offer my bread, the fat and the blood. And they have broken my covenant, to add to all your abominations.", "anderson": "", "haweis": "", "noyes": "in that ye brought strangers, uncircumcised in heart and uncircumcised in flesh, to be in my sanctuary, so that ye polluted my house when ye offered my food, the fat and the blood, and broke my covenant by all your abominations.", "webster": "In that ye have brought [into my sanctuary] strangers, uncircumcised in heart, and uncircumcised in flesh, to be in my sanctuary, to pollute it, [even] my house, when ye offer my bread, the fat and the blood, and they have broken my covenant because of all your abominations.", "vulgate": "eo quod inducitis filios alienos incircumcisos corde et incircumcisos carne ut sint in sanctuario meo et polluant domum meam et offertis panes meos adipem et sanguinem et dissolvitis pactum meum in omnibus sceleribus vestris;", "brenton": "that ye have brought in aliens, uncircumcised in heart, and uncircumcised in flesh, to be in my sanctuary, and to profane it, when ye offered bread, flesh, and blood; and ye transgressed my covenant by all your iniquities;"}}, {"v": 8, "ref": "44:8", "o": "וְ/לֹ֥א שְׁמַרְתֶּ֖ם מִשְׁמֶ֣רֶת קָדָשָׁ֑/י וַ/תְּשִׂימ֗וּ/ן לְ/שֹׁמְרֵ֧י מִשְׁמַרְתִּ֛/י בְּ/מִקְדָּשִׁ֖/י לָ/כֶֽם", "en": {"kjv": "And ye have not kept the charge of mine holy things: but ye have set keepers of my charge in my sanctuary for yourselves.", "web": "You have not performed the duty of my holy things; but you have set performers of my duty in my sanctuary for yourselves.", "bsb": "And you have not kept charge of My holy things, but have appointed others to keep charge of My sanctuary for you.’", "asv": "And ye have not kept the charge of my holy things; but ye have set keepers of my charge in my sanctuary for yourselves.", "ylt": "and ye have not kept the charge of My holy things, and ye set them for keepers of My charge in My sanctuary for you.", "dra": "And you have not kept the ordinances of my sanctuary: but you have set keepers of my charge in my sanctuary for yourselves.", "bbe": "And you have not taken care of my holy things; but you have put them as keepers to take care of my work in my holy place.", "geneva": "For yee haue not kept the ordinances of mine holy things: but you your selues haue set other to take the charge of my Sanctuarie.", "wycliffe": "And ye kepten not the comaundementis of my seyntuarie, and ye settiden keperis of my kepyngis in my seyntuarye to you silf.", "rotherham": "Neither kept ye the charge of my holy things,- But ye did set men to be keepers of my charge in my sanctuary, for your own pleasure,", "darby": "And ye have not kept the charge of my holy things, but have set keepers of my charge in my sanctuary for yourselves.", "twenty": "", "jps": "And ye have not kept the charge of My holy things; but ye have set keepers of My charge in My sanctuary to please yourselves.", "acv": "And ye have not kept the charge of my holy things, but ye have set keepers of my charge in my sanctuary for yourselves.", "anderson": "", "haweis": "", "noyes": "And ye kept not the charge of my holy place, but appointed for yourselves such keepers of my charge in my sanctuary.", "webster": "And ye have not kept the charge of my holy things: but ye have set keepers of my charge in my sanctuary for yourselves.", "vulgate": "et non servastis praecepta sanctuarii mei et posuistis custodes observationum mearum in sanctuario meo vobismet ipsis;", "brenton": "and ye appointed others to keep the charges in my sanctuary."}}, {"v": 9, "ref": "44:9", "o": "כֹּה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ כָּל בֶּן נֵכָ֗ר עֶ֤רֶל לֵב֙ וְ/עֶ֣רֶל בָּשָׂ֔ר לֹ֥א יָב֖וֹא אֶל מִקְדָּשִׁ֑/י לְ/כָל בֶּן נֵכָ֔ר אֲשֶׁ֕ר בְּ/ת֖וֹךְ בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "Thus saith the Lord God; No stranger, uncircumcised in heart, nor uncircumcised in flesh, shall enter into my sanctuary, of any stranger that is among the children of Israel.", "web": "Thus says the Lord Yahweh, No foreigner, uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary, of any foreigners who are among the children of Israel.", "bsb": "This is what the Lord GOD says: No foreigner uncircumcised in heart and flesh may enter My sanctuary—not even a foreigner who lives among the Israelites.", "asv": "Thus saith the Lord Jehovah, No foreigner, uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary, of any foreigners that are among the children of Israel.", "ylt": "`Thus said the Lord Jehovah: No son of a stranger, uncircumcised of heart, and uncircumcised of flesh, cometh in unto My sanctuary, even any son of a stranger, who is in the midst of the sons of Israel,", "dra": "Thus saith the Lord God: No stranger uncircumcised in heart, and uncircumcised in flesh, shall enter into my sanctuary, no stranger that is in the midst of the children of Israel.", "bbe": "For this cause the Lord has said, No man from a strange land, without circumcision of heart and flesh, of all those who are living among the children of Israel, is to come into my holy place.", "geneva": "Thus saieth the Lord God, No stranger vncircumcised in heart, nor vncircumcised in flesh, shall enter into my Sanctuarie, of any stranger that is among the children of Israel,", "wycliffe": "The Lord God seith these thingis, Ech alien `that is vncircumcidid in herte, and vncircumcidid in fleisch, schal not entre in to my seyntuarie; ech alien sone, which is in the myddis of the sones of Israel.", "rotherham": "Thus saith My Lord, Yahweh, No son of a foreigner Uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary,—of any son of a foreigner, who is in the midst of the sons of Israel.", "darby": "Thus saith the Lord Jehovah: No stranger, uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary, of any stranger that is among the children of Israel.", "twenty": "", "jps": "Thus saith the L-rd GOD: No alien, uncircumcised in heart and uncircumcised in flesh, shall enter into My sanctuary, even any alien that is among the children of Israel.", "acv": "Thus says the lord Jehovah: No foreigner, uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary, of any foreigners that are among the sons of Israel.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: No stranger, uncircumcised in heart and uncircumcised in flesh, shall enter into my sanctuary, of all the strangers that are among the sons of Israel.", "webster": "Thus saith the Lord GOD; No stranger, uncircumcised in heart, nor uncircumcised in flesh, shall enter into my sanctuary, of any stranger that [is] among the children of Israel.", "vulgate": "haec dicit Dominus Deus omnis alienigena incircumcisus corde et incircumcisus carne non ingredietur sanctuarium meum omnis filius alienus qui est in medio filiorum Israhel;", "brenton": "Therefore thus saith the Lord God; No alien, uncircumcised in heart or uncircumcised in flesh, shall enter into my sanctuary, of all the children of strangers that are in the midst of the house of Israel."}}, {"v": 10, "ref": "44:10", "o": "כִּ֣י אִם הַ/לְוִיִּ֗ם אֲשֶׁ֤ר רָֽחֲקוּ֙ מֵֽ/עָלַ֔/י בִּ/תְע֤וֹת יִשְׂרָאֵל֙ אֲשֶׁ֣ר תָּע֣וּ מֵֽ/עָלַ֔/י אַחֲרֵ֖י גִּלּֽוּלֵי/הֶ֑ם וְ/נָשְׂא֖וּ עֲוֺנָֽ/ם", "en": {"kjv": "And the Levites that are gone away far from me, when Israel went astray, which went astray away from me after their idols; they shall even bear their iniquity.", "web": "But the Levites who went far from me, when Israel went astray, who went astray from me after their idols, they shall bear their iniquity.", "bsb": "Surely the Levites who wandered away from Me when Israel went astray, and who wandered away from Me after their idols, will bear the consequences of their iniquity.", "asv": "But the Levites that went far from me, when Israel went astray, that went astray from me after their idols, they shall bear their iniquity.", "ylt": "but--the Levites who have gone far off from me, in the wandering of Israel when they went astray from Me after their idols, and they have borne their iniquity.", "dra": "Moreover the Levites that went away far from me, when the children of Israel went astray, and have wandered from me after their idols, and have borne their iniquity:", "bbe": "But as for the Levites, who went far from me, when Israel went out of the right way, turning away from me to go after their images; their punishment will come on them.", "geneva": "Neither yet ye Leuites that are gone backe from me, when Israel went astray, which went astray from thee after their idoles, but they shall beare their iniquitie.", "wycliffe": "But also Leuytis, `ether men of the lynage of Leuy, that yeden fer a wei fro me in the errour of the sones of Israel, and erriden fro me aftir her idols, and baren her wickidnesse,", "rotherham": "But as for the Levites. Who went far from me, when Israel went astray. Who went astray from me, after their manufactured gods, Therefore shall they bear their iniquity,", "darby": "But the Levites who went away far from me, when Israel went astray, going astray from me after their idols, they shall even bear their iniquity;", "twenty": "", "jps": "But the Levites, that went far from Me, when Israel went astray, that went astray from Me after their idols, they shall bear their iniquity;", "acv": "But the Levites who went far from me, when Israel went astray, who went astray from me after their idols, they shall bear their iniquity.", "anderson": "", "haweis": "", "noyes": "But even the Levites, who departed from me when Israel went astray, who went astray from me after their idols, shall bear their iniquity.", "webster": "And the Levites that have gone away far from me, when Israel went astray, who went astray from me after their idols; they shall even bear their iniquity.", "vulgate": "sed et Levitae qui longe recesserunt a me in errore filiorum Israhel et erraverunt a me post idola sua et portaverunt iniquitatem suam;", "brenton": "But as for the Levites who departed far from me when Israel went astray from me after their imaginations, they shall even bear their iniquity."}}, {"v": 11, "ref": "44:11", "o": "וְ/הָי֤וּ בְ/מִקְדָּשִׁ/י֙ מְשָׁ֣רְתִ֔ים פְּקֻדּוֹת֙ אֶל שַׁעֲרֵ֣י הַ/בַּ֔יִת וּֽ/מְשָׁרְתִ֖ים אֶת הַ/בָּ֑יִת הֵ֠מָּה יִשְׁחֲט֨וּ אֶת הָ/עֹלָ֤ה וְ/אֶת הַ/זֶּ֨בַח֙ לָ/עָ֔ם וְ/הֵ֛מָּה יַעַמְד֥וּ לִ/פְנֵי/הֶ֖ם לְ/שָֽׁרְתָֽ/ם", "en": {"kjv": "Yet they shall be ministers in my sanctuary, having charge at the gates of the house, and ministering to the house: they shall slay the burnt offering and the sacrifice for the people, and they shall stand before them to minister unto them.", "web": "Yet they shall be ministers in my sanctuary, having oversight at the gates of the house, and ministering in the house: they shall kill the burnt offering and the sacrifice for the people, and they shall stand before them to minister to them.", "bsb": "Yet they shall be ministers in My sanctuary, having charge of the gates of the temple and ministering there. They shall slaughter the burnt offerings and other sacrifices for the people and stand before them to minister to them.", "asv": "Yet they shall be ministers in my sanctuary, having oversight at the gates of the house, and ministering in the house: they shall slay the burnt-offering and the sacrifice for the people, and they shall stand before them to minister unto them.", "ylt": "And they have been in My sanctuary ministrants, overseers at the gates of the house, and ministrants at the house; they slay the burnt-offering and the sacrifice for the people, and they stand before them to serve them.", "dra": "They shall be officers in my sanctuary, and doorkeepers of the gates of the house, and ministers to the house: they shall slay the holocausts, and the victims of the people: and they shall stand in their sight, to minister to them.", "bbe": "But they may be caretakers in my holy place, and overseers at the doors of the house, doing the work of the house: they will put to death the burned offering and the beasts offered for the people, and they will take their place before them as their servants.", "geneva": "And they shall serue in my Sanctuarie, and keepe the gates of the House, and minister in the House: they shall slay the burnt offring and the sacrifice for the people: and they shall stand before them to serue them.", "wycliffe": "thei schulen be kepers of housis in my seyntuarye, and porteris of yatis of the hous, and mynystris of the hous; thei schulen sle brent sacrifices, and sacrifices for victorie of the puple; and thei schulen stonde in the siyt of the prestis, for to mynystre to hem.", "rotherham": "Yet shall they remain in my sanctuary As attendants in charge at the gates of the house,— And attending upon the house,— They shall slay the ascending-offering, and the sacrifice of the people, And they, shall stand before them to wait upon them.", "darby": "but they shall be ministers in my sanctuary, having oversight at the gates of the house, and doing the service of the house: they shall slaughter the burnt-offering and the sacrifice for the people, and they shall stand before them to minister unto them.", "twenty": "", "jps": "and they shall be ministers in My sanctuary, having charge at the gates of the house, and ministering in the house: they shall slay the burnt-offering and the sacrifice for the people, and they shall stand before them to minister unto them.", "acv": "Yet they shall be ministers in my sanctuary, having oversight at the gates of the house, and ministering in the house. They shall kill the burnt offering and the sacrifice for the people, and they shall stand before them to minister to them.", "anderson": "", "haweis": "", "noyes": "Yet they shall be ministers in my sanctuary, having charge at the gates of the house, and ministering at the house; they shall slay the burnt-offering and sacrifice for the people, and they shall stand before them to minister to them.", "webster": "Yet they shall be ministers in my sanctuary, [having] charge at the gates of the house, and ministering to the house: they shall slay the burnt-offering and the sacrifice for the people, and they shall stand before them to minister to them.", "vulgate": "erunt in sanctuario meo aeditui et ianitores portarum domus et ministri domus ipsi mactabunt holocaustosin et victimas populi et ipsi stabunt in conspectu eorum ut ministrent eis;", "brenton": "yet they shall minister in my sanctuary, being porters at the gates of the house, and serving the house: they shall slay the victims and the whole-burnt-offerings for the people, and they shall stand before the people to minister to them."}}, {"v": 12, "ref": "44:12", "o": "יַ֗עַן אֲשֶׁ֨ר יְשָׁרְת֤וּ אוֹתָ/ם֙ לִ/פְנֵ֣י גִלּֽוּלֵי/הֶ֔ם וְ/הָי֥וּ לְ/בֵֽית יִשְׂרָאֵ֖ל לְ/מִכְשׁ֣וֹל עָוֺ֑ן עַל כֵּן֩ נָשָׂ֨אתִי יָדִ֜/י עֲלֵי/הֶ֗ם נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה וְ/נָשְׂא֖וּ עֲוֺנָֽ/ם", "en": {"kjv": "Because they ministered unto them before their idols, and caused the house of Israel to fall into iniquity; therefore have I lifted up mine hand against them, saith the Lord God, and they shall bear their iniquity.", "web": "Because they ministered to them before their idols, and became a stumbling block of iniquity to the house of Israel; therefore have I lifted up my hand against them, says the Lord Yahweh, and they shall bear their iniquity.", "bsb": "Because they ministered before their idols and became a stumbling block of iniquity to the house of Israel, therefore I swore with an uplifted hand concerning them that they would bear the consequences of their iniquity, declares the Lord GOD.", "asv": "Because they ministered unto them before their idols, and became a stumblingblock of iniquity unto the house of Israel; therefore have I lifted up my hand against them, saith the Lord Jehovah, and they shall bear their iniquity.", "ylt": "Because that they serve them before their idols, and have been to the house of Israel for a stumbling-block of iniquity, therefore I have lifted up my hand against them--an affirmation of the Lord Jehovah--and they have borne their iniquity.", "dra": "Because they ministered to them before their idols, and were a stumblingblock of iniquity to the house of Israel: therefore have I lifted up my hand against them, saith the Lord God, and they shall bear their iniquity:", "bbe": "Because they did this work for them before their images, and became a cause of sin to the children of Israel; for this cause my hand has been lifted up against them, says the Lord, and their punishment will be on them.", "geneva": "Because they serued before their idoles, and caused the house of Israel to fall into iniquitie, therfore haue I lift vp mine had against the, saith the Lord God, and they shall beare their iniquity,", "wycliffe": "For that that thei mynystriden to tho in the siyt of her idols, and weren maad to the hous of Israel in to offendyng of wickidnesse; therfor Y reiside myn hond on them, seith the Lord God, and thei baren her wickidnesse.", "rotherham": "Because they used to wait upon them before their manufactured gods, and became to the house of Israel a stumbling-block of iniquity, For this cause have I lifted up my hand concerning them Declareth My Lord Yahweh, and they shall bear their iniquity;", "darby": "Because they ministered unto them before their idols, and were unto the house of Israel a stumbling-block of iniquity; therefore have I lifted up my hand against them, saith the Lord Jehovah, that they shall bear their iniquity.", "twenty": "", "jps": "Because they ministered unto them before their idols, and became a stumblingblock of iniquity unto the house of Israel; therefore have I lifted up My hand against them, saith the L-rd GOD, and they shall bear their iniquity.", "acv": "Because they ministered to them before their idols, and became a stumbling block of iniquity to the house of Israel, therefore I have lifted up my hand against them, says the lord Jehovah, and they shall bear their iniquity.", "anderson": "", "haweis": "", "noyes": "Because they ministered to them before their idols, and caused the house of Israel to fall into iniquity, therefore have I lifted up my hand against them, saith the Lord Jehovah, that they shall bear their iniquity.", "webster": "Because they ministered to them before their idols, and caused the house of Israel to fall into iniquity; therefore have I lifted up my hand against them, saith the Lord GOD, and they shall bear their iniquity.", "vulgate": "pro eo quod ministraverunt illis in conspectu idolorum suorum et facti sunt domui Israhel in offendiculum iniquitatis idcirco levavi manum meam super eos dicit Dominus Deus et portaverunt iniquitatem suam;", "brenton": "Because they ministered to them before their idols, and it became to the house of Israel a punishment of iniquity; therefore have I lifted up my hand against them, saith the Lord God."}}, {"v": 13, "ref": "44:13", "o": "וְ/לֹֽא יִגְּשׁ֤וּ אֵלַ/י֙ לְ/כַהֵ֣ן לִ֔/י וְ/לָ/גֶ֨שֶׁת֙ עַל כָּל קָ֣דָשַׁ֔/י אֶל קָדְשֵׁ֖י הַ/קְּדָשִׁ֑ים וְ/נָֽשְׂאוּ֙ כְּלִמָּתָ֔/ם וְ/תוֹעֲבוֹתָ֖/ם אֲשֶׁ֥ר עָשֽׂוּ", "en": {"kjv": "And they shall not come near unto me, to do the office of a priest unto me, nor to come near to any of my holy things, in the most holy place: but they shall bear their shame, and their abominations which they have committed.", "web": "They shall not come near to me, to execute the office of priest to me, nor to come near to any of my holy things, to the things that are most holy; but they shall bear their shame, and their abominations which they have committed.", "bsb": "They must not approach Me to serve Me as priests or come near any of My holy things or the most holy things. They will bear the shame of the abominations they have committed.", "asv": "And they shall not come near unto me, to execute the office of priest unto me, nor to come near to any of my holy things, unto the things that are most holy; but they shall bear their shame, and their abominations which they have committed.", "ylt": "And they draw not nigh unto Me to act as My priest, and to draw nigh unto any of My holy things, unto the holy of holies, and they have borne their shame and their abominations that they have done,", "dra": "And they shall not come near to me, to do the office of priest to me, neither shall they come near to any of my holy things that are by the holy of holies: but they shall bear their shame, and their wickednesses which they have committed.", "bbe": "And they will not come near me to do the work of priests to me, or come near any of my holy things, or the things which are most holy: but their shame will be on them, and the punishment for the disgusting things which they have done.", "geneva": "And they shall not come neere vnto me to do ye office of ye Priest vnto me, neyther shall they come neere vnto any of mine holy things in the most holy place, but they shall beare their shame and their abominations, which they haue comitted.", "wycliffe": "And thei schulen not neiye to me, that thei vse preesthod to me, nether thei schulen neiye to al my seyntuarie bisidis hooly of hooli thingis, but thei schulen bere her schenschipe, and her grete trespassis whiche thei diden.", "rotherham": "So then they shall not come near unto me To minister as priests unto me, Nor come near unto any of my holy things, As regardeth things most holy,— But they shall bear their rebuke, and their abominations which they have committed;", "darby": "And they shall not draw near unto me, to do the office of a priest unto me, nor to draw near to any of my holy things, [even] to the most holy; but they shall bear their confusion, and their abominations which they have committed.", "twenty": "", "jps": "And they shall not come near unto Me, to minister unto Me in the priest's office, nor to come near to any of My holy things, unto the things that are most holy; but they shall bear their shame, and their abominations which they have committed.", "acv": "And they shall not come near to me, to execute the office of priest to me, nor to come near to any of my holy things, to the things that are most holy, but they shall bear their shame, and their abominations which they have committed.", "anderson": "", "haweis": "", "noyes": "And they shall not come near to me to do the office of a priest to me, and to come near to any of my holy things in the most holy place, but they shall bear their shame, and their abominations which they have committed.", "webster": "And they shall not come near to me, to do the office of a priest to me, nor to come near to any of my holy things, in the most holy [place]: but they shall bear their shame, and their abominations which they have committed.", "vulgate": "et non adpropinquabunt ad me ut sacerdotio fungantur mihi neque accedent ad omne sanctuarium meum iuxta sancta sanctorum sed portabunt confusionem suam et scelera sua quae fecerunt;", "brenton": "And they shall not draw nigh to me to minister to me in the priests' office, nor to approach the holy things of the children of Israel, nor to approach my holy of holies: but they shall bear their reproach for the error wherein they erred."}}, {"v": 14, "ref": "44:14", "o": "וְ/נָתַתִּ֣י אוֹתָ֔/ם שֹׁמְרֵ֖י מִשְׁמֶ֣רֶת הַ/בָּ֑יִת לְ/כֹל֙ עֲבֹ֣דָת֔/וֹ וּ/לְ/כֹ֛ל אֲשֶׁ֥ר יֵעָשֶׂ֖ה בּֽ/וֹ", "en": {"kjv": "But I will make them keepers of the charge of the house, for all the service thereof, and for all that shall be done therein.", "web": "Yet will I make them performers of the duty of the house, for all its service, and for all that shall be done therein.", "bsb": "Yet I will appoint them to keep charge of all the work for the temple and everything to be done in it.", "asv": "Yet will I make them keepers of the charge of the house, for all the service thereof, and for all that shall be done therein.", "ylt": "and I made them keepers of the charge of the house, for all its service and for all that is done in it.", "dra": "And I will make them doorkeepers of the house, for all the service thereof, and for all that shall be done therein.", "bbe": "But I will make them responsible for the care of the house and all its work and everything which is done in it.", "geneva": "And I will make them keepers of ye watch of the House, for all the seruice thereof, and for all that shalbe done therein.", "wycliffe": "And Y schal make hem porteris of the hous, in al the seruyce therof, and in alle thingis that ben don ther ynne.", "rotherham": "Yet will I make them keepers of the charge of the house,— As to all the labour thereof, and As to all which shall be done therein.", "darby": "And I will make them keepers of the charge of the house, for all the service thereof, and for all that shall be done therein.", "twenty": "", "jps": "And I will make them keepers of the charge of the house, for all the service thereof, and for all that shall be done therein.", "acv": "Yet I will make them keepers of the charge of the house, for all the service of it, and for all that shall be done in it.", "anderson": "", "haweis": "", "noyes": "But I will make them keepers of the charge of the house, for all the service thereof, and for all which is to be done therein.", "webster": "But I will make them keepers of the charge of the house, for all its service, and for all that shall be done therein.", "vulgate": "et dabo eos ianitores domus in omni ministerio eius et universis quae fiunt in ea;", "brenton": "They shall bring them to keep the charges of the house, for all the service of it, and for all that they shall do."}}, {"v": 15, "ref": "44:15", "o": "וְ/הַ/כֹּהֲנִ֨ים הַ/לְוִיִּ֜ם בְּנֵ֣י צָד֗וֹק אֲשֶׁ֨ר שָׁמְר֜וּ אֶת מִשְׁמֶ֤רֶת מִקְדָּשִׁ/י֙ בִּ/תְע֤וֹת בְּנֵֽי יִשְׂרָאֵל֙ מֵֽ/עָלַ֔/י הֵ֛מָּה יִקְרְב֥וּ אֵלַ֖/י לְ/שָֽׁרְתֵ֑/נִי וְ/עָמְד֣וּ לְ/פָנַ֗/י לְ/הַקְרִ֥יב לִ/י֙ חֵ֣לֶב וָ/דָ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "But the priests the Levites, the sons of Zadok, that kept the charge of my sanctuary when the children of Israel went astray from me, they shall come near to me to minister unto me, and they shall stand before me to offer unto me the fat and the blood, saith the Lord God:", "web": "But the priests the Levites, the sons of Zadok, who performed the duty of my sanctuary when the children of Israel went astray from me, they shall come near to me to minister to me; and they shall stand before me to offer to me the fat and the blood, says the Lord Yahweh:", "bsb": "But the Levitical priests, who are descended from Zadok and who kept charge of My sanctuary when the Israelites went astray from Me, are to approach Me to minister before Me. They will stand before Me to offer Me fat and blood, declares the Lord GOD.", "asv": "But the priests the Levites, the sons of Zadok, that kept the charge of my sanctuary when the children of Israel went astray from me, they shall come near to me to minister unto me; and they shall stand before me to offer unto me the fat and the blood, saith the Lord Jehovah:", "ylt": "`And the priests, the Levites, sons of Zadok, who have kept the charge of My sanctuary in the wandering of the sons of Israel from off Me, they draw near unto Me to serve Me, and have stood before Me, to bring near to Me fat and blood--an affirmation of the Lord Jehovah:", "dra": "But the priests, and Levites, the sons of Sadoc, who kept the ceremonies of my sanctuary, when the children of Israel went astray from me, they shall come near to me, to minister to me: and they shall stand before me, to offer me the fat, and the blood, saith the Lord God.", "bbe": "But as for the priests, the sons of Zadok, who took care of my holy place when the children of Israel were turned away from me, they are to come near me to do my work, they will take their places before me, offering to me the fat and the blood, says the Lord;", "geneva": "But the Priests of the Leuites, the sonnes of Zadok, that kept the charge of my Sanctuarie, when the children of Israel went astray from me, they shall come neere to me to serue me, and they shall stande before me to offer me the fat and the blood, saith the Lord God.", "wycliffe": "Forsothe preestis and dekenes, the sones of Sadoch, that kepten the cerymonyes of my seyntuarie, whanne the sones of Israel erriden fro me, thei schulen neiye to me, for to mynystre to me; and thei schulen stonde in my siyt, that thei offre to me ynnere fatnesse and blood, seith the Lord God.", "rotherham": "But the priests the Levites the sons of Zadok, Who kept the charge of my sanctuary— when the sons of Israel went astray from me, They shall draw near unto me to wait upon me, And shall stand before me, to bring near unto me the fat and the blood Declareth My Lord, Yahweh:", "darby": "But the priests, the Levites, the sons of Zadok, that kept the charge of my sanctuary when the children of Israel went astray from me, they shall approach unto me to minister unto me, and they shall stand before me to present unto me the fat and the blood, saith the Lord Jehovah.", "twenty": "", "jps": "But the priests the Levites, the sons of Zadok, that kept the charge of My sanctuary when the children of Israel went astray from Me, they shall come near to Me to minister unto Me; and they shall stand before Me to offer unto Me the fat and the blood, saith the L-rd GOD;", "acv": "But the priests the Levites, the sons of Zadok, who kept the charge of my sanctuary when the sons of Israel went astray from me, they shall come near to me to minister to me. And they shall stand before me to offer to me the fat and the blood, says the lord Jehovah:", "anderson": "", "haweis": "", "noyes": "But the priests, the Levites, the sons of Zadok, that kept the charge of my sanctuary when the sons of Israel went astray from me, they shall come near to me to minister to me, and they shall stand before me to offer to me the fat and the blood, saith the Lord Jehovah.", "webster": "But the priests the Levites, the sons of Zadok, that kept the charge of my sanctuary when the children of Israel went astray from me, they shall come near to me to minister to me, and they shall stand before me to offer to me the fat and the blood, saith the Lord GOD:", "vulgate": "sacerdotes autem Levitae filii Sadoc qui custodierunt caerimonias sanctuarii mei cum errarent filii Israhel a me ipsi accedent ad me ut ministrent mihi et stabunt in conspectu meo ut offerant mihi adipem et sanguinem ait Dominus Deus;", "brenton": "The priests the Levites, the sons of Sadduc, who kept the charges of my sanctuary when the house of Israel went astray from me, these shall draw night to me to minister to me, and shall stand before my face, to offer sacrifice to me, the fat and the blood, saith the Lord God."}}, {"v": 16, "ref": "44:16", "o": "הֵ֜מָּה יָבֹ֣אוּ אֶל מִקְדָּשִׁ֗/י וְ/הֵ֛מָּה יִקְרְב֥וּ אֶל שֻׁלְחָנִ֖/י לְ/שָׁרְתֵ֑/נִי וְ/שָׁמְר֖וּ אֶת מִשְׁמַרְתִּֽ/י", "en": {"kjv": "They shall enter into my sanctuary, and they shall come near to my table, to minister unto me, and they shall keep my charge.", "web": "they shall enter into my sanctuary, and they shall come near to my table, to minister to me, and they shall keep my instruction.", "bsb": "They alone shall enter My sanctuary and draw near to My table to minister before Me. They will keep My charge.", "asv": "they shall enter into my sanctuary, and they shall come near to my table, to minister unto me, and they shall keep my charge.", "ylt": "they come in unto My sanctuary, and they draw near unto My table to serve Me, and they have kept My charge.", "dra": "They shall enter into my sanctuary, and they shall come near to my table, to minister unto me, and to keep my ceremonies.", "bbe": "They are to come into my holy place and they are to come near to my table, to do my work and have the care of my house.", "geneva": "They shall enter into my Sanctuarie, and shall come neere to my table, to serue me, and they shall keepe my charge.", "wycliffe": "Thei schulen entre in to my seyntuarie, and thei schulen neiye to my boord, that thei mynystre to me, and kepe my ceremonyes.", "rotherham": "They shall enter into my sanctuary, and They shall draw near unto my table to wait upon me,- So shall they keep my charge.", "darby": "They shall enter into my sanctuary, and they shall approach unto my table, to minister unto me, and they shall keep my charge.", "twenty": "", "jps": "they shall enter into My sanctuary, and they shall come near to My table, to minister unto Me, and they shall keep My charge.", "acv": "they shall enter into my sanctuary, and they shall come near to my table, to minister to me, and they shall keep my charge.", "anderson": "", "haweis": "", "noyes": "They shall come into my sanctuary, and they shall draw near to my table to minister to me, and shall keep my charge.", "webster": "They shall enter into my sanctuary, and they shall come near to my table, to minister to me, and they shall keep my charge.", "vulgate": "ipsi ingredientur sanctuarium meum et ipsi accedent ad mensam meam ut ministrent mihi et custodiant caerimonias meas;", "brenton": "These shall enter into my sanctuary, and these shall approach my table, to minister to me, and they shall keep my charges."}}, {"v": 17, "ref": "44:17", "o": "וְ/הָיָ֗ה בְּ/בוֹאָ/ם֙ אֶֽל שַׁעֲרֵי֙ הֶ/חָצֵ֣ר הַ/פְּנִימִ֔ית בִּגְדֵ֥י פִשְׁתִּ֖ים יִלְבָּ֑שׁוּ וְ/לֹֽא יַעֲלֶ֤ה עֲלֵי/הֶם֙ צֶ֔מֶר בְּ/שָֽׁרְתָ֗/ם בְּ/שַׁעֲרֵ֛י הֶ/חָצֵ֥ר הַ/פְּנִימִ֖ית וָ/בָֽיְתָ/ה", "en": {"kjv": "And it shall come to pass, that when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, whiles they minister in the gates of the inner court, and within.", "web": "It shall be that, when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come on them, while they minister in the gates of the inner court, and within.", "bsb": "When they enter the gates of the inner court, they are to wear linen garments; they must not wear anything made of wool when they minister at the gates of the inner court or inside the temple.", "asv": "And it shall be that, when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, while they minister in the gates of the inner court, and within.", "ylt": "And it hath come to pass, in their going in unto the gates of the inner court, linen garments they put on; and no wool cometh up on them in their ministering in the gates of the inner court and within.", "dra": "And when they shall enter in at the gates of the inner court, they shall be clothed with linen garments: neither shall any woollen come upon them, when they minister in the gates of the inner court and within.", "bbe": "And when they come in by the doorways of the inner square, they are to be clothed in linen robes; there is to be no wool on them while they are doing my work in the doorway of the inner square and inside the house.", "geneva": "And whe they shall enter in at the gates of the inner court, they shall be clothed with linen garments, and no wool shall come vpon the while they serue in ye gates of the inner court, and within.", "wycliffe": "And whanne thei schulen entre in to the yatis of the ynnere halle,", "rotherham": "And it shall be when they shall enter into the gates of the inner court, Garments of linen, shall they put on, Yea there shall come upon them no wool, when they minister in the gates of the inner court and within:", "darby": "And it shall come to pass when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, when they minister in the gates of the inner court, and towards the house.", "twenty": "", "jps": "And it shall be that when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, while they minister in the gates of the inner court, and within.", "acv": "And it shall be that, when they enter in at the gates of the inner court, they shall be clothed with linen garments, and no wool shall come upon them, while they minister in the gates of the inner court, and within.", "anderson": "", "haweis": "", "noyes": "And when they enter the gates of the inner court, they shall be clothed with linen garments, and no wool shall come upon them while they minister in the gates of the inner court, and within the house.", "webster": "And it shall come to pass, [that] when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, while they minister in the gates of the inner court, and within.", "vulgate": "cumque ingredientur portas atrii interioris vestibus lineis induentur nec ascendet super eos quicquam laneum quando ministrant in portis atrii interioris et intrinsecus;", "brenton": "And it shall come to pass when they enter the gates of the inner court, that they shall put on linen robes; and they shall not put on woollen garments when they minister at the gate of the inner court."}}, {"v": 18, "ref": "44:18", "o": "פַּאֲרֵ֤י פִשְׁתִּים֙ יִהְי֣וּ עַל רֹאשָׁ֔/ם וּ/מִכְנְסֵ֣י פִשְׁתִּ֔ים יִהְי֖וּ עַל מָתְנֵי/הֶ֑ם לֹ֥א יַחְגְּר֖וּ בַּ/יָּֽזַע", "en": {"kjv": "They shall have linen bonnets upon their heads, and shall have linen breeches upon their loins; they shall not gird themselves with any thing that causeth sweat.", "web": "They shall have linen tires on their heads, and shall have linen breeches on their waists; they shall not clothe themselves with anything that makes them sweat.", "bsb": "They are to wear linen turbans on their heads and linen undergarments around their waists. They must not wear anything that makes them perspire.", "asv": "They shall have linen tires upon their heads, and shall have linen breeches upon their loins; they shall not gird themselves with anything that causeth sweat.", "ylt": "Linen bonnets are on their head, and linen trousers are on their loins, they are not restrained with sweat.", "dra": "They shall have linen mitres on their heads, and linen breeches on their loins, and they shall not be girded with any thing that causeth sweat.", "bbe": "They are to have linen head-dresses on their heads and linen trousers on their legs, and they are to have nothing round them to make their skin wet with heat.", "geneva": "They shall haue linnen bonets vpon their heades, and shall haue linnen breeches vpon their loynes: they shall not girde them selues in the sweating places.", "wycliffe": "thei schulen be clothid with lynnun clothis, nether ony wollun thing schal `be do on hem, whanne thei mynystren in the yatis of the ynnere halle, and with ynne; lynnun cappis, ether mytris, schulen be in the heedis of hem, and lynnun brechis schulen be in the leendis of hem, and thei schulen not be gird in swoot.", "rotherham": "Chaplets of linen, shall be upon their head, and Breeches of linen shall be upon their loins,— They shall not gird themselves, so as to perspire,", "darby": "They shall have linen tires upon their heads, and shall have linen breeches upon their loins; they shall not gird on anything that causeth sweat.", "twenty": "", "jps": "They shall have linen tires upon their heads, and shall have linen breeches upon their loins; they shall not gird themselves with any thing that causeth sweat.", "acv": "They shall have linen headdresses upon their heads, and shall have linen breeches upon their loins. They shall not gird themselves with anything that causes sweat.", "anderson": "", "haweis": "", "noyes": "They shall have linen coverings upon their heads, and linen breeches upon their loins; they shall not gird themselves with anything that causeth sweat.", "webster": "They shall have linen bonnets upon their heads, and shall have linen breeches upon their loins; they shall not gird [themselves] with any thing that causeth sweat.", "vulgate": "vittae lineae erunt in capitibus eorum et feminalia linea erunt in lumbis eorum et non accingentur in sudore;", "brenton": "And they shall have linen mitres upon their heads, and shall have linen drawers upon their loins; and they shall not tightly gird themselves."}}, {"v": 19, "ref": "44:19", "o": "וּ֠/בְ/צֵאתָ/ם אֶל הֶ/חָצֵ֨ר הַ/חִיצוֹנָ֜ה אֶל הֶ/חָצֵ֣ר הַ/חִיצוֹנָה֮ אֶל הָ/עָם֒ יִפְשְׁט֣וּ אֶת בִּגְדֵי/הֶ֗ם אֲשֶׁר הֵ֨מָּה֙ מְשָׁרְתִ֣ם בָּ֔/ם וְ/הִנִּ֥יחוּ אוֹתָ֖/ם בְּ/לִֽשְׁכֹ֣ת הַ/קֹּ֑דֶשׁ וְ/לָֽבְשׁוּ֙ בְּגָדִ֣ים אֲחֵרִ֔ים וְ/לֹֽא יְקַדְּשׁ֥וּ אֶת הָ/עָ֖ם בְּ/בִגְדֵי/הֶֽם", "en": {"kjv": "And when they go forth into the utter court, even into the utter court to the people, they shall put off their garments wherein they ministered, and lay them in the holy chambers, and they shall put on other garments; and they shall not sanctify the people with their garments.", "web": "When they go out into the outer court, even into the outer court to the people, they shall put off their garments in which they minister, and lay them in the holy rooms; and they shall put on other garments, that they not sanctify the people with their garments.", "bsb": "When they go out to the outer court, to the people, they are to take off the garments in which they have ministered, leave them in the holy chambers, and dress in other clothes so that they do not transmit holiness to the people with their garments.", "asv": "And when they go forth into the outer court, even into the outer court to the people, they shall put off their garments wherein they minister, and lay them in the holy chambers; and they shall put on other garments, that they sanctify not the people with their garments.", "ylt": "And in their going forth unto the outer court--unto the outer court unto the people--they strip off their garments, in which they are ministering, and have placed them in the holy chambers, and have put on other garments; and they do not sanctify the people in their own garments.", "dra": "And when they shall go forth to the outward court to the people, they shall put off their garments wherein they ministered, and lay them up in the store chamber of the sanctuary, and they shall clothe themselves with other garments: and they shall not sanctify the people with their vestments.", "bbe": "And when they go out into the outer square to the people, they are to take off the robes in which they do the work of priests, and put them away in the holy rooms, and put on other clothing, so that the people may not be made holy by their robes.", "geneva": "But when they goe foorth into the vtter court, euen to the vtter court to the people, they shall put off their garments, wherein they ministred, and lay them in the holy chambers, and they shall put on other garments: for they shall not sanctifie the people with their garments.", "wycliffe": "And whanne thei schulen go out at the outermere halle to the puple, thei schulen dispuyle hem of her clothis, in whiche thei mynystriden, and thei schulen leie tho vp in the treserie of seyntuarie; and thei schulen clothe hem silf in othere clothis, and thei schulen not halewe my puple in her clothis.", "rotherham": "And when they go forth into the outer court into the outer court unto the people, They shall put off their garments, wherein they do minister, and lay them in the chambers of the holy place,- And shall put on other garments, That they may not hallow the people by their garments.", "darby": "And when they go forth into the outer court, into the outer court to the people, they shall put off their garments wherein they ministered, and lay them in the holy cells; and they shall put on other garments, that they may not hallow the people with their garments.", "twenty": "", "jps": "And when they go forth into the outer court, even into the outer court to the people, they shall put off their garments wherein they minister, and lay them in the holy chambers, and they shall put on other garments, that they sanctify not the people with their garments.", "acv": "And when they go forth into the outer court, even into the outer court to the people, they shall put off their garments in which they minister, and lay them in the holy chambers. And they shall put on other garments, that they not sanctify the people with their garments.", "anderson": "", "haweis": "", "noyes": "And when they go forth into the outer court, even into the outer court to the people, they shall put off their garments in which they ministered, and lay them in the holy rooms, and shall clothe themselves with other garments, that they may not sanctify the people with their garments.", "webster": "And when they go forth into the outer court, [even] into the outer court to the people, they shall put off their garments in which they ministered, and lay them in the holy chambers, and they shall put on other garments; and they shall not sanctify the people with their garments.", "vulgate": "cumque egredientur atrium exterius ad populum exuent se vestimenta sua in quibus ministraverunt et reponent ea in gazofilacio sanctuarii et vestient se vestimentis aliis et non sanctificabunt populum in vestibus suis;", "brenton": "And when they go out into the outer court to the people, they shall put off their robes, in which they minister; and they shall lay them up in the chambers of the sanctuary, and shall put on other robes, and they shall not sanctify the people with their robes."}}, {"v": 20, "ref": "44:20", "o": "וְ/רֹאשָׁ/ם֙ לֹ֣א יְגַלֵּ֔חוּ וּ/פֶ֖רַע לֹ֣א יְשַׁלֵּ֑חוּ כָּס֥וֹם יִכְסְמ֖וּ אֶת רָאשֵׁי/הֶֽם", "en": {"kjv": "Neither shall they shave their heads, nor suffer their locks to grow long; they shall only poll their heads.", "web": "Neither shall they shave their heads, nor allow their locks to grow long; they shall only cut off the hair of their heads.", "bsb": "They must not shave their heads or let their hair grow long, but must carefully trim their hair.", "asv": "Neither shall they shave their heads, nor suffer their locks to grow long; they shall only cut off the hair of their heads.", "ylt": "And their head they do not shave, and the lock they do not send forth; they certainly poll their heads.", "dra": "Neither shall they shave their heads, nor wear long hair: but they shall only poll their heads.", "bbe": "They are not to have all the hair cut off their heads, and they are not to let their hair get long, but they are to have the ends of their hair cut.", "geneva": "They shall not also shaue their heades, nor suffer their lockes to growe long, but rounde their heades.", "wycliffe": "Forsothe thei schulen not schaue her heed, nether thei schulen nursche long heere, but thei clippynge schulen clippe her heedis.", "rotherham": "And their heads, shall they not shave, Nor let the hair grow long,— They shall only poll, their heads.", "darby": "Neither shall they shave their heads, nor suffer their locks to grow long: they shall duly poll their heads.", "twenty": "", "jps": "Neither shall they shave their heads, nor suffer their locks to grow long; they shall only poll their heads.", "acv": "Neither shall they shave their heads, nor allow their locks to grow long. They shall only cut off the hair of their heads.", "anderson": "", "haweis": "", "noyes": "They shall neither shave their heads, nor suffer their locks to grow long; they shall shear their heads.", "webster": "Neither shall they shave their heads, nor suffer their locks to grow long; they shall only poll their heads.", "vulgate": "caput autem suum non radent neque comam nutrient sed tondentes adtondent capita sua;", "brenton": "And they shall not shave their heads, nor shall they pluck off their hair; they shall carefully cover their heads."}}, {"v": 21, "ref": "44:21", "o": "וְ/יַ֥יִן לֹֽא יִשְׁתּ֖וּ כָּל כֹּהֵ֑ן בְּ/בוֹאָ֖/ם אֶל הֶ/חָצֵ֥ר הַ/פְּנִימִֽית", "en": {"kjv": "Neither shall any priest drink wine, when they enter into the inner court.", "web": "Neither shall any of the priests drink wine, when they enter into the inner court.", "bsb": "No priest may drink wine before he enters the inner court.", "asv": "Neither shall any of the priests drink wine, when they enter into the inner court.", "ylt": "And no priest doth drink wine in their coming in unto the inner court.", "dra": "And no priest shall drink wine when he is to go into the inner court.", "bbe": "The priests are not to take wine when they go into the inner square.", "geneva": "Neither shall any Priest drinke wine when they enter into the inner court.", "wycliffe": "And ech preest schal not drynke wyn, whanne he schal entre in to the ynnere halle.", "rotherham": "And wine, shall no priest drink,—when they enter into the inner court.", "darby": "Neither shall any priest drink wine when they enter into the inner court.", "twenty": "", "jps": "Neither shall any priest drink wine, when they enter into the inner court.", "acv": "Neither shall any of the priests drink wine when they enter into the inner court.", "anderson": "", "haweis": "", "noyes": "And no priest shall drink wine when they enter into the inner court.", "webster": "Neither shall any priest drink wine, when they enter into the inner court.", "vulgate": "et vinum non bibet omnis sacerdos quando ingressurus est atrium interius;", "brenton": "And no priest shall drink any wine, when they go into the inner court."}}, {"v": 22, "ref": "44:22", "o": "וְ/אַלְמָנָה֙ וּ/גְרוּשָׁ֔ה לֹֽא יִקְח֥וּ לָ/הֶ֖ם לְ/נָשִׁ֑ים כִּ֣י אִם בְּתוּלֹ֗ת מִ/זֶּ֨רַע֙ בֵּ֣ית יִשְׂרָאֵ֔ל וְ/הָֽ/אַלְמָנָה֙ אֲשֶׁ֣ר תִּֽהְיֶ֣ה אַלְמָנָ֔ה מִ/כֹּהֵ֖ן יִקָּֽחוּ", "en": {"kjv": "Neither shall they take for their wives a widow, nor her that is put away: but they shall take maidens of the seed of the house of Israel, or a widow that had a priest before.", "web": "Neither shall they take for their wives a widow, nor her who is put away; but they shall take virgins of the seed of the house of Israel, or a widow who is the widow of a priest.", "bsb": "And they shall not marry a widow or a divorced woman, but must marry a virgin of the descendants of the house of Israel, or a widow of a priest.", "asv": "Neither shall they take for their wives a widow, nor her that is put away; but they shall take virgins of the seed of the house of Israel, or a widow that is the widow of a priest.", "ylt": "And a widow and divorced woman they do not take to them for wives: but--virgins of the seed of the house of Israel, and the widow who is widow of a priest, do they take.", "dra": "Neither shall they take to wife a widow, nor one that is divorced, but they shall take virgins of the seed of the house of Israel: but they may take a widow also, that is, the widow of a priest.", "bbe": "And they are not to take as wives any widow or woman whose husband has put her away: but they may take virgins of the seed of Israel, or a widow who is the widow of a priest.", "geneva": "Neither shall they take for their wiues a widowe, or her that is diuorced: but they shall take maidens of the seede of the house of Israel, or a widow that hath bene the widow of a Priest.", "wycliffe": "And preestis schulen not take wyues a widewe, and a forsakun womman, but virgyns of the seed of the hous of Israel; but also thei schulen take a widewe, which is the widewe of a preest.", "rotherham": "Neither widow nor divorced woman, shall they take to them to wife,— But, virgins of the seed of the house of Israel, Or a widow who shall be the widow of a priest shall they take.", "darby": "And they shall not take for their wives a widow, nor her that is put away; but they shall take maidens of the seed of the house of Israel, or a widow that is the widow of a priest.", "twenty": "", "jps": "Neither shall they take for their wives a widow, nor her that is put away; but they shall take virgins of the seed of the house of Israel, or a widow that is the widow of a priest.", "acv": "Neither shall they take for their wives a widow, nor her who is put away, but they shall take virgins of the seed of the house of Israel, or a widow who is the widow of a priest.", "anderson": "", "haweis": "", "noyes": "Neither shall they take for their wives a widow, or her that is put away; but they shall take virgins of the race of the house of Israel, or a widow that is the widow of a priest.", "webster": "Neither shall they take for their wives a widow, nor her that is put away: but they shall take maidens of the seed of the house of Israel, or a widow that had a priest before.", "vulgate": "et viduam et repudiatam non accipient uxores sed virgines de semine domus Israhel sed et viduam quae fuerit vidua a sacerdote accipient;", "brenton": "Neither shall they take to themselves to wife a widow, or one that is put away, but a virgin of the seed of Israel: but if there should happen to be a priest's widow, they shall take her."}}, {"v": 23, "ref": "44:23", "o": "וְ/אֶת עַמִּ֣/י יוֹר֔וּ בֵּ֥ין קֹ֖דֶשׁ לְ/חֹ֑ל וּ/בֵין טָמֵ֥א לְ/טָה֖וֹר יוֹדִעֻֽ/ם", "en": {"kjv": "And they shall teach my people the difference between the holy and profane, and cause them to discern between the unclean and the clean.", "web": "They shall teach my people the difference between the holy and the common, and cause them to discern between the unclean and the clean.", "bsb": "They are to teach My people the difference between the holy and the common, and show them how to discern between the clean and the unclean.", "asv": "And they shall teach my people the difference between the holy and the common, and cause them to discern between the unclean and the clean.", "ylt": "`And My people they direct between holy and common, and between unclean and clean they cause them to discern.", "dra": "And they shall teach my people the difference between holy and profane, and shew them how to discern between clean and unclean.", "bbe": "And they are to make clear to my people the division between what is holy and what is common, and to give them the knowledge of what is clean and what is unclean.", "geneva": "And they shall teach my people the difference betweene the holy and prophane, and cause them to discerne betweene the vncleane and the cleane.", "wycliffe": "And thei schulen teche my puple, what is bitwixe hooli thing and defoulid; and thei schulen schewe to hem, what is bitwixe cleene thing and vncleene.", "rotherham": "And my people, shall they instruct, between the holy and the common,— And between the unclean and the clean, shall they cause them to distinguish.", "darby": "And they shall teach my people [the difference] between holy and profane, and cause them to discern between unclean and clean.", "twenty": "", "jps": "And they shall teach My people the difference between the holy and the common, and cause them to discern between the unclean and the clean.", "acv": "And they shall teach my people the difference between the holy and the common, and cause them to discern between the unclean and the clean.", "anderson": "", "haweis": "", "noyes": "And they shall teach my people the difference between the holy and unholy, and cause them to discern between the unclean and the clean.", "webster": "And they shall teach my people the [difference] between the holy and profane, and cause them to discern between the unclean and the clean.", "vulgate": "et populum meum docebunt quid sit inter sanctum et pollutum et inter mundum et inmundum ostendent eis;", "brenton": "And they shall teach my people to distinguish between holy and profane, and they shall make known to them the difference between unclean and clean."}}, {"v": 24, "ref": "44:24", "o": "וְ/עַל רִ֗יב הֵ֚מָּה יַעַמְד֣וּ ל/שפט לְ/מִשְׁפָּ֔ט בְּ/מִשְׁפָּטַ֖/י ו/שפט/הו יִשְׁפְּט֑וּ/הוּ וְ/אֶת תּוֹרֹתַ֤/י וְ/אֶת חֻקֹּתַ/י֙ בְּ/כָל מוֹעֲדַ֣/י יִשְׁמֹ֔רוּ וְ/אֶת שַׁבְּתוֹתַ֖/י יְקַדֵּֽשׁוּ", "en": {"kjv": "And in controversy they shall stand in judgment; and they shall judge it according to my judgments: and they shall keep my laws and my statutes in all mine assemblies; and they shall hallow my sabbaths.", "web": "In a controversy they shall stand to judge; according to my ordinances shall they judge it: and they shall keep my laws and my statutes in all my appointed feasts; and they shall make my Sabbaths holy.", "bsb": "In any dispute, they shall officiate as judges and judge according to My ordinances. They must keep My laws and statutes regarding all My appointed feasts, and they must keep My Sabbaths holy.", "asv": "And in a controversy they shall stand to judge; according to mine ordinances shall they judge it: and they shall keep my laws and my statutes in all my appointed feasts; and they shall hallow my sabbaths.", "ylt": "And concerning controversy, they stand up for judgment; with My judgments they judge it; and My law and My statutes in all My appointed places they keep; and My sabbaths they sanctify.", "dra": "And when there shall be a controversy, they shall stand in my judgments, and shall judge: they shall keep my laws, and my ordinances in all my solemnities, and sanctify my sabbaths.", "bbe": "In any cause, they are to be in the position of judges, judging in harmony with my decisions: they are to keep my laws and my rules in all my fixed feasts; and they are to keep my Sabbaths holy.", "geneva": "And in controuersie they shall stande to iudge, and they shall iudge it according to my iudgements: and they shall keepe my lawes and my statutes in all mine assemblies, and they shall sanctifie my Sabbaths.", "wycliffe": "And whanne debate is, thei schulen stonde in my domes, and schulen deme my lawis; and thei schulen kepe my comaundementis in alle my solempnytees, and thei schulen halewe my sabatis.", "rotherham": "And in a controversy, They shall stand up for justice, With my judgments, shall they judge it, And my laws and my statutes in all mine appointed assemblies, shall they observe, And my sabbaths, shall they hallow.", "darby": "And in controversy they shall stand to judge: they shall judge it according to my judgments; and they shall keep my laws and my statutes in all my solemnities; and they shall hallow my sabbaths.", "twenty": "", "jps": "And in a controversy they shall stand to judge; according to Mine ordinances shall they judge it; and they shall keep My laws and My statutes in all My appointed seasons, and they shall hallow My sabbaths.", "acv": "And in a controversy they shall stand to judge. They shall judge it according to my ordinances. And they shall keep my laws and my statutes in all my appointed feasts, and they shall hallow my sabbaths.", "anderson": "", "haweis": "", "noyes": "And in controversy they shall stand to judge; according to my statutes shall they judge. And they shall keep my laws and my statutes in all my festivals, and they shall hallow my sabbaths.", "webster": "And in controversy they shall stand in judgment; [and] they shall judge it according to my judgments: and they shall keep my laws and my statutes in all my assemblies; and they shall hallow my sabbaths.", "vulgate": "et cum fuerit controversia stabunt in iudiciis meis et iudicabunt leges meas et praecepta mea in omnibus sollemnitatibus meis custodient et sabbata mea sanctificabunt;", "brenton": "And these shall attend at a judgment of blood to decide it: they shall rightly observe my ordinances, and judge my judgments, and keep my statutes and my commandments in all my feasts; and they shall hallow my sabbaths."}}, {"v": 25, "ref": "44:25", "o": "וְ/אֶל מֵ֣ת אָדָ֔ם לֹ֥א יָב֖וֹא לְ/טָמְאָ֑ה כִּ֣י אִם לְ/אָ֡ב וּ֠/לְ/אֵם וּ/לְ/בֵ֨ן וּ/לְ/בַ֜ת לְ/אָ֗ח וּ/לְ/אָח֛וֹת אֲשֶֽׁר לֹא הָיְתָ֥ה לְ/אִ֖ישׁ יִטַּמָּֽאוּ", "en": {"kjv": "And they shall come at no dead person to defile themselves: but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.", "web": "They shall go in to no dead person to defile themselves; but for father, or for mother, or for son, or for daughter, for brother, or for sister who has had no husband, they may defile themselves.", "bsb": "A priest must not defile himself by going near a dead person. However, for a father, a mother, a son, a daughter, a brother, or an unmarried sister, he may do so,", "asv": "And they shall go in to no dead person to defile themselves; but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.", "ylt": "And unto any dead man they come not for uncleanness, but for father, and for mother, and for son, and for daughter, for brother, for sister who hath not been to a man, they defile themselves.", "dra": "And they shall come near no dead person, lest they be defiled, only their father and mother, and son and daughter, and brother and sister, that hath not had another husband: for whom they may become unclean.", "bbe": "They are not to come near any dead person so as to become unclean: but for a father or mother or son or daughter or brother or for a sister who has no husband, they may make themselves unclean.", "geneva": "And they shall come at no dead person to defile theselues, except at their father, or mother, or sone, or daughter, brother or sister, that hath had yet none husband: in these may they be defiled.", "wycliffe": "And thei schulen not entre to a deed man, lest thei be defoulid, no but to fadir, and modir, and to sone, and douyter, and to brother, and sister that hadde not an hosebonde, in whiche thei schulen be defoulid.", "rotherham": "And unto no dead person, shall they go in. to defile themselves,- Save that for father or for mother or for son or for daughter, for brother or for sister who hath belonged to no husband they may defile themselves.", "darby": "And they shall come at no dead person to become unclean; but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may become unclean.", "twenty": "", "jps": "And they shall come near no dead person to defile themselves; but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.", "acv": "And they shall go in to no dead person to defile themselves. But for father, or for mother, or for son, or for daughter, for brother, or for sister who has had no husband, they may defile themselves.", "anderson": "", "haweis": "", "noyes": "And they shall come to no dead person to defile themselves; but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.", "webster": "And they shall come at no dead person to defile themselves: but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.", "vulgate": "et ad mortuum hominem non ingredientur ne polluantur nisi ad patrem et matrem et filium et filiam et fratrem et sororem quae alterum virum non habuit in quibus contaminabuntur;", "brenton": "And they shall not go in to the dead body of a man to defile themselves: only a priest may defile himself for a father, or for a mother, or for a son, or for a daughter, or for a brother, or for his sister, who has not been married."}}, {"v": 26, "ref": "44:26", "o": "וְ/אַחֲרֵ֖י טָֽהֳרָת֑/וֹ שִׁבְעַ֥ת יָמִ֖ים יִסְפְּרוּ לֽ/וֹ", "en": {"kjv": "And after he is cleansed, they shall reckon unto him seven days.", "web": "After he is cleansed, they shall reckon to him seven days.", "bsb": "and after he is cleansed, he must count off seven days for himself.", "asv": "And after he is cleansed, they shall reckon unto him seven days.", "ylt": "`And after his cleansing, seven days they number to him.", "dra": "And after one is cleansed, they shall reckon unto him seven days.", "bbe": "And after he has been made clean, seven days are to be numbered for him.", "geneva": "And when he is clensed, they shall reckon vnto him seuen dayes.", "wycliffe": "And after that he is clensid, seuene daies schulen be noumbrid to hym.", "rotherham": "Yet after he is cleansed, seven days shall they count to him.", "darby": "And after he is cleansed, they shall count unto him seven days.", "twenty": "", "jps": "And after he is cleansed, they shall reckon unto him seven days.", "acv": "And after he is cleansed, they shall reckon to him seven days.", "anderson": "", "haweis": "", "noyes": "And after his cleansing they shall reckon to him seven days.", "webster": "And after he is cleansed, they shall reckon to him seven days.", "vulgate": "et postquam fuerit emundatus septem dies numerabuntur ei;", "brenton": "And after he has been cleansed, let him number to himself seven days."}}, {"v": 27, "ref": "44:27", "o": "וּ/בְ/יוֹם֩ בֹּא֨/וֹ אֶל הַ/קֹּ֜דֶשׁ אֶל הֶ/חָצֵ֤ר הַ/פְּנִימִית֙ לְ/שָׁרֵ֣ת בַּ/קֹּ֔דֶשׁ יַקְרִ֖יב חַטָּאת֑/וֹ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And in the day that he goeth into the sanctuary, unto the inner court, to minister in the sanctuary, he shall offer his sin offering, saith the Lord God.", "web": "In the day that he goes into the sanctuary, into the inner court, to minister in the sanctuary, he shall offer his sin offering, says the Lord Yahweh.", "bsb": "And on the day he goes into the sanctuary, into the inner court, to minister in the sanctuary, he must present his sin offering, declares the Lord GOD.", "asv": "And in the day that he goeth into the sanctuary, into the inner court, to minister in the sanctuary, he shall offer his sin-offering, saith the Lord Jehovah.", "ylt": "And in the day of his coming in unto the sanctuary, unto the inner court, to minister in the sanctuary, he bringeth near his sin-offering--an affirmation of the Lord Jehovah.", "dra": "And in the day that he goeth into the sanctuary, to the inner court, to minister unto me in the sanctuary, he shall offer for his sin, saith the Lord God.", "bbe": "And on the day when he goes into the inner square, to do the work of the holy place, he is to make his sin-offering, says the Lord.", "geneva": "And when he goeth into ye Sanctuarie vnto the inner court to minister in the Sanctuarie, he shall offer his sinne offring, saith ye Lord God.", "wycliffe": "And in the dai of his entryng in to the seyntuarie, to the ynnere halle, that he mynystre to me in the seyntuarie, he schal offre for his synne, seith the Lord God.", "rotherham": "And in the day when he entereth into the sanctuary, into the inner court to minister in the sanctuary, He shall bring near his sin-bearer, Declareth My Lord Yahweh.", "darby": "And on the day that he goeth into the sanctuary, unto the inner court, to minister in the sanctuary, he shall present his sin-offering, saith the Lord Jehovah.", "twenty": "", "jps": "And in the day that he goeth into the sanctuary, into the inner court, to minister in the sanctuary, he shall offer his sin-offering, saith the L-rd GOD.", "acv": "And in the day that he goes into the sanctuary, into the inner court, to minister in the sanctuary, he shall offer his sin offering, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And in the day that he goeth into the sanctuary, into the inner court, to minister in the sanctuary, he shall offer his sin-offering, saith the Lord Jehovah.", "webster": "And in the day that he goeth into the sanctuary, to the inner court, to minister in the sanctuary, he shall offer his sin-offering, saith the Lord GOD.", "vulgate": "et in die introitus sui in sanctuarium ad atrium interius ut ministret mihi in sanctuario offeret pro peccato suo ait Dominus Deus;", "brenton": "And on whatsoever day they shall enter into the inner court to minister in the holy place, they shall bring a propitiation, saith the Lord God."}}, {"v": 28, "ref": "44:28", "o": "וְ/הָיְתָ֤ה לָ/הֶם֙ לְֽ/נַחֲלָ֔ה אֲנִ֖י נַֽחֲלָתָ֑/ם וַ/אֲחֻזָּ֗ה לֹֽא תִתְּנ֤וּ לָ/הֶם֙ בְּ/יִשְׂרָאֵ֔ל אֲנִ֖י אֲחֻזָּתָֽ/ם", "en": {"kjv": "And it shall be unto them for an inheritance: I am their inheritance: and ye shall give them no possession in Israel: I am their possession.", "web": "They shall have an inheritance: I am their inheritance; and you shall give them no possession in Israel; I am their possession.", "bsb": "In regard to their inheritance, I am their inheritance. You are to give them no possession in Israel, for I am their possession.", "asv": "And they shall have an inheritance: I am their inheritance; and ye shall give them no possession in Israel; I am their possession.", "ylt": "And it hath been to them for an inheritance; I am their inheritance: and a possession ye do not give to them in Israel; I am their possession.", "dra": "And they shall have no inheritance, I am their inheritance: neither shall you give them any possession in Israel, for I am their possession.", "bbe": "And they are to have no heritage; I am their heritage: you are to give them no property in Israel; I am their property.", "geneva": "And the Priesthood shall bee their inheritance, yea, I am their inheritance: therefore shall ye giue them no possessio in Israel, for I am their possession.", "wycliffe": "Forsothe noon eritage schal be to hem, Y am the eritage of hem; and ye schulen not yyue to hem possessioun in Israel, for Y am the possessioun of hem.", "rotherham": "So shall it become to them an inheritance, I, am their inheritance,- And possession, shall ye not give them in Israel, I am their possession.", "darby": "And it shall be unto them for an inheritance; I am their inheritance: and ye shall give them no possession in Israel; I am their possession.", "twenty": "", "jps": "And it shall be unto them for an inheritance: I am their inheritance; and ye shall give them no possession in Israel: I am their possession.", "acv": "And they shall have an inheritance: I am their inheritance. And ye shall give them no possession in Israel. I am their possession.", "anderson": "", "haweis": "", "noyes": "And it shall be to them for an inheritance, that I am their inheritance. And ye shall give them no possession in Israel; I am their possession.", "webster": "And it shall be to them for an inheritance: I [am] their inheritance: and ye shall give them no possession in Israel: I [am] their possession.", "vulgate": "erit autem eis hereditas ego hereditas eorum et possessionem non dabitis eis in Israhel ego enim possessio eorum;", "brenton": "And it shall be to them for an inheritance: I am their inheritance: and no possession shall be given them among the children of Israel; for I am their possession."}}, {"v": 29, "ref": "44:29", "o": "הַ/מִּנְחָה֙ וְ/הַ/חַטָּ֣את וְ/הָ/אָשָׁ֔ם הֵ֖מָּה יֹֽאכְל֑וּ/ם וְ/כָל חֵ֥רֶם בְּ/יִשְׂרָאֵ֖ל לָ/הֶ֥ם יִהְיֶֽה", "en": {"kjv": "They shall eat the meat offering, and the sin offering, and the trespass offering; and every dedicated thing in Israel shall be theirs.", "web": "They shall eat the meal offering, and the sin offering, and the trespass offering; and every devoted thing in Israel shall be theirs.", "bsb": "They shall eat the grain offerings, the sin offerings, and the guilt offerings. Everything in Israel devoted to the LORD will belong to them.", "asv": "They shall eat the meal-offering, and the sin-offering, and the trespass-offering; and every devoted thing in Israel shall be theirs.", "ylt": "The present, and the sin-offering, and the guilt-offering, they do eat, and every devoted thing in Israel is theirs.", "dra": "They shall eat the victim both for sin and for trespass: and every vowed thing in Israel shall be theirs.", "bbe": "Their food is to be the meal offering and the sin-offering and the offering for error; and everything given specially to the Lord in Israel will be theirs.", "geneva": "They shall eate the meat offring, and the sinne offring, and the trespas offring, and euery dedicate thing in Israel shall be theirs.", "wycliffe": "Thei schulen ete sacrifice, bothe for synne and for trespasse, and ech avow of Israel schal be hern.", "rotherham": "As for the meal-offering and the sin-bearer and the guilt-bearer, they shall eat them, —And everything devoted in Israel to them, shall belong.", "darby": "They shall eat the oblation and the sin-offering and the trespass-offering; and every devoted thing in Israel shall be theirs.", "twenty": "", "jps": "The meal-offering, and the sin-offering, and the guilt-offering, they, even they, shall eat; and every devoted thing in Israel shall be theirs.", "acv": "They shall eat the meal offering, and the sin offering, and the trespass offering. And every devoted thing in Israel shall be theirs.", "anderson": "", "haweis": "", "noyes": "They shall eat the flour-offering, and the sin-offering, and the trespass-offering; and every dedicated thing in Israel shall be theirs.", "webster": "They shall eat the meat-offering, and the sin-offering, and the trespass-offering; and every dedicated thing in Israel shall be theirs.", "vulgate": "victimam et pro peccato et pro delicto ipsi comedent et omne votum in Israhel ipsorum erit;", "brenton": "And these shall eat the meat-offerings, and the sin-offerings, and the trespass-offerings; and every special offering in Israel shall be theirs."}}, {"v": 30, "ref": "44:30", "o": "וְ/רֵאשִׁית֩ כָּל בִּכּ֨וּרֵי כֹ֜ל וְ/כָל תְּר֣וּמַת כֹּ֗ל מִ/כֹּל֙ תְּרוּמ֣וֹתֵי/כֶ֔ם לַ/כֹּהֲנִ֖ים יִֽהְיֶ֑ה וְ/רֵאשִׁ֤ית עֲרִסֽוֹתֵי/כֶם֙ תִּתְּנ֣וּ לַ/כֹּהֵ֔ן לְ/הָנִ֥יחַ בְּרָכָ֖ה אֶל בֵּיתֶֽ/ךָ", "en": {"kjv": "And the first of all the firstfruits of all things, and every oblation of all, of every sort of your oblations, shall be the priest’s: ye shall also give unto the priest the first of your dough, that he may cause the blessing to rest in thine house.", "web": "The first of all the first fruits of every thing, and every offering of everything, of all your offerings, shall be for the priest: you shall also give to the priests the first of your dough, to cause a blessing to rest on your house.", "bsb": "The best of all the firstfruits and of every contribution from all your offerings will belong to the priests. You are to give your first batch of dough to the priest, so that a blessing may rest upon your homes.", "asv": "And the first of all the first-fruits of every thing, and every oblation of everything, of all your oblations, shall be for the priest: ye shall also give unto the priests the first of your dough, to cause a blessing to rest on thy house.", "ylt": "And the first of all the first-fruits of all, and every heave-offering of all, of all your heave-offerings, are the priests': and the first of your dough ye give to the priest, to cause a blessing to rest on thy house.", "dra": "And the firstfruits of all the firstborn, and all the libations of all things that are offered, shall be the priest's: and you shall give the firstfruits of your meats to the priest, that he may return a blessing upon thy house.", "bbe": "And the best of all the first-fruits of everything, and every offering which is lifted up of all your offerings, will be for the priests: and you are to give the priest the first of your bread-making, so causing a blessing to come on your house.", "geneva": "And all the first of all the first borne, and euery oblation, euen all of euery sort of your oblations shall be the Priestes. Ye shall also giue vnto the Priest the first of your dough, that he may cause the blessing to rest in thine house.", "wycliffe": "And the firste thingis of alle firste gendrid thingis, and alle moiste sacrifices, of alle thingis that ben offrid, schulen be the prestis part; and ye schulen yyue the firste thingis of youre metis to the prest, that he leie vp blessyng to his hous.", "rotherham": "And the first of all the firstfruits of everything, and every heave-offering of everything, from among all your heave-offerings to the priests, shall it belong,— The first of your meal, shall ye give to the priest, To cause a blessing to rest upon by house.", "darby": "And the first of all the first-fruits of every [kind], and every heave-offering of every [kind], of all your heave-offerings, shall be for the priests; ye shall also give unto the priest the first of your dough, that he may cause the blessing to rest on thy house.", "twenty": "", "jps": "And the first of all the first-fruits of every thing, and every heave-offering of every thing, of all your offerings, shall be for the priests; ye shall also give unto the priest the first of your dough, to cause a blessing to rest on thy house.", "acv": "And the first of all the first-fruits of every thing, and every oblation of everything, of all your oblations, shall be for the priest. Ye shall also give to the priests the first of your dough, to cause a blessing to rest on thy house.", "anderson": "", "haweis": "", "noyes": "And the first of all the first-fruits, and every oblation of all your oblations, shall belong to the priests. Ye shall also give to the priest the first of your meal, that he may cause a blessing to rest on thine house.", "webster": "And the first of all the first-fruits of all [things], and every oblation of all, of every [sort] of your oblations, shall be the priest's: ye shall also give to the priest the first of your dough, that he may cause the blessing to rest in thy house.", "vulgate": "et primitiva omnium primogenitorum et omnia libamenta ex omnibus quae offeruntur sacerdotum erunt et primitiva ciborum vestrorum dabitis sacerdoti ut reponat benedictionem domui suae;", "brenton": "And the first-fruits of all things, and the first-born of all animals and all offerings, of all your first-fruits there shall be a share for the priests; and ye shall give your earliest produce to the priest, to bring your blessings upon your houses."}}, {"v": 31, "ref": "44:31", "o": "כָּל נְבֵלָה֙ וּ/טְרֵפָ֔ה מִן הָ/ע֖וֹף וּ/מִן הַ/בְּהֵמָ֑ה לֹ֥א יֹאכְל֖וּ הַ/כֹּהֲנִֽים", "en": {"kjv": "The priests shall not eat of any thing that is dead of itself, or torn, whether it be fowl or beast.", "web": "The priests shall not eat of anything that dies of itself, or is torn, whether it be bird or animal.", "bsb": "The priests may not eat any bird or animal found dead or torn by wild beasts.", "asv": "The priests shall not eat of anything that dieth of itself, or is torn, whether it be bird or beast.", "ylt": "Any carcase and torn thing, of the fowl, and of the beasts, the priests do not eat.", "dra": "The priests shall not eat of any thing that is dead of itself or caught by a beast, whether it be fowl or cattle.", "bbe": "The priests may not take for food any bird or beast which has come to a natural death or whose death has been caused by another animal.", "geneva": "The Priests shall not eate of any thing, that is dead, or torne, whether it be foule or beast.", "wycliffe": "Preestis schulen not ete ony thing deed bi it silf, and takun of a beeste, of foulis, and of scheep.", "rotherham": "Nothing that died of itself or was torn in pieces, of bird or of beast shall be eaten by the priests.", "darby": "The priests shall not eat of anything that dieth of itself, or of that which is torn, whether of fowl or of beast.", "twenty": "", "jps": "The priests shall not eat of any thing that dieth of itself, or is torn, whether it be fowl or beast.", "acv": "The priests shall not eat of anything that dies of itself, or is torn, whether it be bird or beast.", "anderson": "", "haweis": "", "noyes": "The priests shall not eat of anything that dieth of itself, or that is torn, whether it be fowl or beast.", "webster": "The priests shall not eat of any thing that is dead of itself, or torn, whether of fowl or beast.", "vulgate": "omne morticinum et captum a bestia de avibus et de pecoribus non comedent sacerdotes;", "brenton": "And the priests shall eat no bird or beast that dies of itself, or is taken of wild beasts."}}]}, {"c": 45, "verses": [{"v": 1, "ref": "45:1", "o": "וּ/בְ/הַפִּֽילְ/כֶ֨ם אֶת הָ/אָ֜רֶץ בְּ/נַחֲלָ֗ה תָּרִימוּ֩ תְרוּמָ֨ה לַ/יהוָ֥ה קֹדֶשׁ֮ מִן הָ/אָרֶץ֒ אֹ֗רֶךְ חֲמִשָּׁ֨ה וְ/עֶשְׂרִ֥ים אֶ֨לֶף֙ אֹ֔רֶךְ וְ/רֹ֖חַב עֲשָׂ֣רָה אָ֑לֶף קֹדֶשׁ ה֥וּא בְ/כָל גְּבוּלָ֖/הּ סָבִֽיב", "en": {"kjv": "Moreover, when ye shall divide by lot the land for inheritance, ye shall offer an oblation unto the Lord, an holy portion of the land: the length shall be the length of five and twenty thousand reeds, and the breadth shall be ten thousand. This shall be holy in all the borders thereof round about.", "web": "Moreover, when you shall divide by lot the land for inheritance, you shall offer an offering to Yahweh, a holy portion of the land; the length shall be the length of twenty-five thousand reeds, and the breadth shall be ten thousand: it shall be holy in all its border all around.", "bsb": "“When you divide the land by lot as an inheritance, you are to set aside a portion for the LORD, a holy portion of the land 25,000 cubits long and 20,000 cubits wide. This entire tract of land will be holy.", "asv": "Moreover, when ye shall divide by lot the land for inheritance, ye shall offer an oblation unto Jehovah, a holy portion of the land; the length shall be the length of five and twenty thousand reeds, and the breadth shall be ten thousand: it shall be holy in all the border thereof round about.", "ylt": "And in your causing the land to fall in inheritance, ye lift up a heave-offering to Jehovah, a holy portion of the land: the length--five and twenty thousand is the length, and the breadth ten thousand; it is holy in all its border round about.", "dra": "And when you shall begin to divide the land by lot, separate ye firstfruits to the Lord, a portion of the land to be holy, in length twenty-five thousand and in breadth ten thousand: it shall be holy in all the borders thereof round about.", "bbe": "And when you are making a distribution of the land, by the decision of the Lord, for your heritage, you are to make an offering to the Lord of a part of the land as holy: it is to be twenty-five thousand long and twenty thousand wide: all the land inside these limits is to be holy.", "geneva": "Moreover when yee shall deuide the land for inheritance, ye shall offer an oblation vnto the Lord an holy portion of the land, fiue and twentie thousand reedes long, and ten thousand broad: this shalbe holy in all the borders thereof round about.", "wycliffe": "And whanne ye schulen bigynne to departe the lond bi partis, departe ye the firste thingis to the Lord, an halewid thing of the lond, fyue and twenti thousynde of rehedis in lengthe, and ten thousynde of rehedis in breede; it schal be halewid in al the coost therof by cumpas.", "rotherham": "And when ye shall by lot divide the land as an inheritance, ye shall offer up as a heave-offering to Yahweh a holy portion out of the land, in length, five and twenty thousand long, and in breadth, twenty thousand, —holy shall it be throughout all the territory thereof round about.", "darby": "And when ye shall divide by lot the land for inheritance, ye shall offer a heave-offering unto Jehovah, a holy portion of the land: the length shall be the length of five and twenty thousand [cubits], and the breadth ten thousand. This shall be holy in all the borders thereof round about.", "twenty": "", "jps": "Moreover, when ye shall divide by lot the land for inheritance, ye shall set apart an offering unto HaShem, a holy portion of the land; the length shall be the length of five and twenty thousand reeds, and the breadth shall be ten thousand; it shall be holy in all the border thereof round about.", "acv": "Moreover, when ye shall divide the land by lot for inheritance, ye shall offer an oblation to Jehovah, a holy portion of the land. The length shall be the length of twenty-five thousand measures, and the breadth shall be ten thousand. It shall be holy in all the border of it round about.", "anderson": "", "haweis": "", "noyes": "Moreover, when ye shall divide by lot the land for inheritance, ye shall offer an oblation to Jehovah, a holy portion of the land; the length shall be five and twenty thousand reeds, and the breadth ten thousand. This shall be holy in all its borders round about.", "webster": "Moreover, when ye shall divide by lot the land for inheritance, ye shall offer an oblation to the LORD, a holy portion of the land: the length [shall be] the length of five and twenty thousand [reeds], and the breadth [shall be] ten thousand. This [shall be] holy in all its borders on every side.", "vulgate": "cumque coeperitis terram dividere sortito separate primitias Domino sanctificatum de terra longitudine viginti quinque milia et latitudine decem milia sanctificatum erit in omni termino eius per circuitum;", "brenton": "And when ye measure the land for inheritance, ye shall set apart first-fruits to the Lord, a holy space of the land, in length twenty and five thousand reeds, and in breadth twenty thousand; it shall be holy in all the borders thereof round about."}}, {"v": 2, "ref": "45:2", "o": "יִהְיֶ֤ה מִ/זֶּה֙ אֶל הַ/קֹּ֔דֶשׁ חֲמֵ֥שׁ מֵא֛וֹת בַּ/חֲמֵ֥שׁ מֵא֖וֹת מְרֻבָּ֣ע סָבִ֑יב וַ/חֲמִשִּׁ֣ים אַמָּ֔ה מִגְרָ֥שׁ ל֖/וֹ סָבִֽיב", "en": {"kjv": "Of this there shall be for the sanctuary five hundred in length, with five hundred in breadth, square round about; and fifty cubits round about for the suburbs thereof.", "web": "Of this there shall be a five hundred by five hundred square for the holy place; and fifty cubits for its suburbs all around.", "bsb": "Within this area there is to be a section for the sanctuary 500 cubits square, with 50 cubits around it for open land.", "asv": "Of this there shall be for the holy place five hundred in length by five hundred in breadth, square round about; and fifty cubits for the suburbs thereof round about.", "ylt": "There is of this for the sanctuary five hundred by five hundred, square, round about; and fifty cubits of suburb is to it round about.", "dra": "And there shall be for the sanctuary on every side five hundred by five hundred, foursquare round about: and fifty cubits for the suburbs thereof round about.", "bbe": "Of this, a square five hundred long and five hundred wide is to be for the holy place, with a space of fifty cubits all round it.", "geneva": "Of this there shalbe for the Sanctuarie fiue hundreth in length with fiue hundreth in breadth, all square round about, and fiftie cubites rounde about for the suburbes thereof.", "wycliffe": "And it schal be halewid on ech part in fyue hundrid rehedis bi fyue hundrid, in foure sidis bi cumpas, and in fifti cubitis in to the subarbis therof bi cumpas.", "rotherham": "There shall be out of this for the holy place, five hundred by five hundred, four-square round about,—and fifty cubits, as an open space to it, round about,", "darby": "Of this there shall be for the sanctuary five hundred [reeds] by five hundred, square round about; and fifty cubits round about for the suburbs thereof.", "twenty": "", "jps": "Of this there shall be for the holy place five hundred in length by five hundred in breadth, square round about; and fifty cubits for the open land round about it.", "acv": "Of this there shall be for the holy place five hundred by five hundred square round about, and fifty cubits for the suburbs of it round about.", "anderson": "", "haweis": "", "noyes": "And of this there shall be for the sanctuary five hundred in length and five hundred in breadth square round about; and fifty cubits round about for the suburbs thereof.", "webster": "Of this there shall be for the sanctuary five hundred [in length], with five hundred [in breadth], square around; and fifty cubits around for the suburbs of it.", "vulgate": "et erit ex omni parte sanctificatum quingentos per quingentos quadrifariam per circuitum et quinquaginta cubitis in suburbana eius per gyrum;", "brenton": "And there shall be a sanctuary out of this, five hundred reeds in length by five hundred in breadth, a square round about; and there shall be a vacant space beyond this of fifty cubits round about."}}, {"v": 3, "ref": "45:3", "o": "וּ/מִן הַ/מִּדָּ֤ה הַ/זֹּאת֙ תָּמ֔וֹד אֹ֗רֶךְ חמש חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף וְ/רֹ֖חַב עֲשֶׂ֣רֶת אֲלָפִ֑ים וּ/בֽ/וֹ יִהְיֶ֥ה הַ/מִּקְדָּ֖שׁ קֹ֥דֶשׁ קָדָשִֽׁים", "en": {"kjv": "And of this measure shalt thou measure the length of five and twenty thousand, and the breadth of ten thousand: and in it shall be the sanctuary and the most holy place.", "web": "Of this measure you shall measure a length of twenty-five thousand, and a breadth of ten thousand: and in it shall be the sanctuary, which is most holy.", "bsb": "From this holy portion, you are to measure off a length of 25,000 cubits and a width of 10,000 cubits, and in it will be the sanctuary, the Most Holy Place.", "asv": "And of this measure shalt thou measure a length of five and twenty thousand, and a breadth of ten thousand: and in it shall be the sanctuary, which is most holy.", "ylt": "And by this measure thou dost measure: the length is five and twenty thousand, and the breadth ten thousand: and in it is the sanctuary, the holy of holies.", "dra": "And with this measure thou shalt measure the length of five and twenty thousand, and the breadth of ten thousand, and in it shall be the temple and the holy of holies.", "bbe": "And of this measure, let a space be measured, twenty-five thousand long and ten thousand wide: in it there will be the holy place, even the most holy.", "geneva": "And of this measure shalt thou measure the length of fiue and twentie thousande, and the breadth of tenne thousande: and in it shalbe the Sanctuarie, and the most holy place.", "wycliffe": "And fro this mesure thou schalt mete the lengthe of fyue and twenti thousynde of rehedis, and the breede of ten thousynde; and the temple and the hooli of hooli thingis schal be in it.", "rotherham": "And out of this measure, shalt thou measure, a length of five and twenty thousand and a breadth of ten thousand,—and therein, shall be the sanctuary, the holy of holies:", "darby": "And of this measure shalt thou measure the length of five and twenty thousand, and the breadth of ten thousand; and in it shall be the sanctuary, the holy of holies.", "twenty": "", "jps": "And of this measure shalt thou measure a length of five and twenty thousand, and a breadth of ten thousand; and in it shall be the sanctuary, which is most holy.", "acv": "And of this measure thou shall measure a length of twenty-five thousand, and a breadth of ten thousand. And the sanctuary shall be in it, which is most holy.", "anderson": "", "haweis": "", "noyes": "And of this measure shalt thou measure in length five and twenty thousand, and in breadth ten thousand; and in it shall be the sanctuary, the most holy place.", "webster": "And of this measure shalt thou measure the length of five and twenty thousand, and the breadth of ten thousand: and in it shall be the sanctuary [and] the most holy [place].", "vulgate": "et a mensura ista mensurabis longitudinem viginti quinque milium et latitudinem decem milium et in ipso erit templum sanctumque sanctorum;", "brenton": "And out of this measurement shalt thou measure the length five and twenty thousand, and the breadth twenty thousand: and in it shall be the holy of holies."}}, {"v": 4, "ref": "45:4", "o": "קֹ֣דֶשׁ מִן הָ/אָ֜רֶץ ה֗וּא לַ/כֹּ֨הֲנִ֜ים מְשָׁרְתֵ֤י הַ/מִּקְדָּשׁ֙ יִֽהְיֶ֔ה הַ/קְּרֵבִ֖ים לְ/שָׁרֵ֣ת אֶת יְהוָ֑ה וְ/הָיָ֨ה לָ/הֶ֤ם מָקוֹם֙ לְ/בָ֣תִּ֔ים וּ/מִקְדָּ֖שׁ לַ/מִּקְדָּֽשׁ", "en": {"kjv": "The holy portion of the land shall be for the priests the ministers of the sanctuary, which shall come near to minister unto the Lord: and it shall be a place for their houses, and an holy place for the sanctuary.", "web": "It is a holy portion of the land; it shall be for the priests, the ministers of the sanctuary, who come near to minister to Yahweh; and it shall be a place for their houses, and a holy place for the sanctuary.", "bsb": "It will be a holy portion of the land to be used by the priests who minister in the sanctuary, who draw near to minister before the LORD. It will be a place for their houses, as well as a holy area for the sanctuary.", "asv": "It is a holy portion of the land; it shall be for the priests, the ministers of the sanctuary, that come near to minister unto Jehovah; and it shall be a place for their houses, and a holy place for the sanctuary.", "ylt": "The holy portion of the land it is ; for priests, ministrants of the sanctuary, it is, who are drawing near to serve Jehovah; and it hath been to them a place for houses, and a holy place for a sanctuary.", "dra": "The holy portion of the land shall be for the priests the ministers of the sanctuary, who come near to the ministry of the Lord: and it shall be a place for their houses, and for the holy place of the sanctuary.", "bbe": "This holy part of the land is to be for the priests, the servants of the holy place, who come near to the Lord to do his work; it is to be a place for their houses and for grass-land and for cattle.", "geneva": "The holy portion of the lande shalbe the Priests, which minister in the Sanctuarie, which came neere to serue the Lord: and it shalbe a place for their houses, and an holy place for the Sanctuarie.", "wycliffe": "An halewid thing of the lond schal be to prestis, the mynystris of seyntuarie, that neiyen to the seruyce of the Lord; and a place schal be to hem in to housis, and in to the seyntuarie of hoolynesse.", "rotherham": "a holy portion out of the land, it is for the priests who wait in the sanctuary, shall it be, who draw near to wait upon Yahweh,- so shall it be theirs as a place for houses, and a sanctuary for the sanctuary.", "darby": "This is the holy [portion] of the land; it shall be for the priests who do the service of the sanctuary, who draw near to serve Jehovah, and it shall be a place for their houses, and a holy place for the sanctuary.", "twenty": "", "jps": "It is a holy portion of the land; it shall be for the priests, the ministers of the sanctuary, that come near to minister unto HaShem; and it shall be a place for their houses, and a place consecrated for the sanctuary.", "acv": "It is a holy portion of the land. It shall be for the priests, the ministers of the sanctuary, who come near to minister to Jehovah, and it shall be a place for their houses, and a holy place for the sanctuary.", "anderson": "", "haweis": "", "noyes": "This is the holy portion of the land; it shall be for the priests, the ministers of the sanctuary, who come near to minister to Jehovah; and it shall be a place for their houses, and a holy place for the sanctuary.", "webster": "The holy [portion] of the land shall be for the priests the ministers of the sanctuary, who shall come near to minister to the LORD: and it shall be a place for their houses, and a holy place for the sanctuary.", "vulgate": "sanctificatum de terra erit sacerdotibus ministris sanctuarii qui accedunt ad ministerium Domini et erit eis locus in domos et in sanctuarium sanctitatis;", "brenton": "Of the land shall be a portion for the priests that minister in the holy place, and it shall be for them that draw nigh to minister to the Lord: and it shall be to them a place for houses set apart for their sacred office;"}}, {"v": 5, "ref": "45:5", "o": "וַ/חֲמִשָּׁ֨ה וְ/עֶשְׂרִ֥ים אֶ֨לֶף֙ אֹ֔רֶךְ וַ/עֲשֶׂ֥רֶת אֲלָפִ֖ים רֹ֑חַב יהיה וְֽ/הָיָ֡ה לַ/לְוִיִּם֩ מְשָׁרְתֵ֨י הַ/בַּ֧יִת לָ/הֶ֛ם לַ/אֲחֻזָּ֖ה עֶשְׂרִ֥ים לְשָׁכֹֽת", "en": {"kjv": "And the five and twenty thousand of length, and the ten thousand of breadth, shall also the Levites, the ministers of the house, have for themselves, for a possession for twenty chambers.", "web": "Twenty-five thousand in length, and ten thousand in breadth, shall be to the Levites, the ministers of the house, for a possession to themselves, for twenty rooms.", "bsb": "An adjacent area 25,000 cubits long and 10,000 cubits wide shall belong to the Levites who minister in the temple; it will be their possession for towns in which to live.", "asv": "And five and twenty thousand in length, and ten thousand in breadth, shall be unto the Levites, the ministers of the house, for a possession unto themselves, for twenty chambers.", "ylt": "`And of the five and twenty thousand of length, and of the ten thousand of breadth, there is to the Levites, ministrants of the house, for them--for a possession--twenty chambers.", "dra": "And five and twenty thousand of length, and ten thousand of breadth shall be for the Levites, that minister in the house: they shall possess twenty store chambers.", "bbe": "A space of land twenty-five thousand long and ten thousand wide is to be for the Levites, the servants of the house, a property for themselves, for towns for their living-places.", "geneva": "And in the fiue and twentie thousande of length, and the ten thousand of breadth shall the Leuites that minister in the house, haue their possession for twentie chambers.", "wycliffe": "Sotheli fyue and twenti thousynde of lengthe schulen be, and ten thousynde of breede; but the dekenes that mynystren to the hous, thei schulen haue in possessioun twenti treseries.", "rotherham": "And five and twenty thousand, in length, and ten thousand, in breadth,—and it shall be for the Levites who wait upon the house theirs as a possession of cities to dwell in", "darby": "And [a space of] five and twenty thousand in length, and ten thousand in breadth, shall the Levites, who do the service of the house, have for themselves, for a possession, for their habitations.", "twenty": "", "jps": "And five and twenty thousand in length, and ten thousand in breadth, which shall be unto the Levites, the ministers of the house, for a possession unto themselves, for twenty chambers.", "acv": "And twenty-five thousand in length, and ten thousand in breadth, shall be to the Levites, the ministers of the house, for a possession to themselves, for twenty chambers.", "anderson": "", "haweis": "", "noyes": "Five and twenty thousand in length, and ten thousand in breadth, shall the Levites, the ministers of the house, have for themselves for a possession, and twenty rooms.", "webster": "And the five and twenty thousand of length, and the ten thousand of breadth, shall also the Levites, the ministers of the house, have for themselves, for a possession for twenty chambers.", "vulgate": "viginti quinque autem milia longitudinis et decem milia latitudinis erunt Levitis qui ministrant domui ipsi possidebunt viginti gazofilacia;", "brenton": "the length shall be twenty-five thousand, and the breadth twenty thousand: and the Levites that attend the house, they shall have cities to dwell in for a possession."}}, {"v": 6, "ref": "45:6", "o": "וַ/אֲחֻזַּ֨ת הָ/עִ֜יר תִּתְּנ֗וּ חֲמֵ֤שֶׁת אֲלָפִים֙ רֹ֔חַב וְ/אֹ֗רֶךְ חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף לְ/עֻמַּ֖ת תְּרוּמַ֣ת הַ/קֹּ֑דֶשׁ לְ/כָל בֵּ֥ית יִשְׂרָאֵ֖ל יִהְיֶֽה", "en": {"kjv": "And ye shall appoint the possession of the city five thousand broad, and five and twenty thousand long, over against the oblation of the holy portion: it shall be for the whole house of Israel.", "web": "You shall appoint the possession of the city five thousand broad, and twenty-five thousand long, side by side with the offering of the holy portion: it shall be for the whole house of Israel.", "bsb": "As the property of the city, you are to set aside an area 5,000 cubits wide and 25,000 cubits long, adjacent to the holy district. It will belong to the whole house of Israel.", "asv": "And ye shall appoint the possession of the city five thousand broad, and five and twenty thousand long, side by side with the oblation of the holy portion: it shall be for the whole house of Israel.", "ylt": "`And of the possession of the city ye give five thousand of breadth, and of length five and twenty thousand, over-against the heave-offering of the holy portion : to all the house of Israel it is.", "dra": "And you shall appoint the possession of the city five thousand broad, and five and twenty thousand long, according to the separation of the sanctuary, for the whole house of Israel.", "bbe": "And as the property for the town you are to have a part five thousand wide and twenty-five thousand long, by the side of the offering of the holy part of the land: this is to be for all the children of Israel.", "geneva": "Also ye shall appoynt the possession of the citie, fiue thousand broad, and fiue and twentie thousand log ouer against the oblation of ye holy portion: it shalbe for the whole house of Israel.", "wycliffe": "And ye schulen yyue the possessioun of the citee, fyue thousynde rehedis of breede, and fyue and twenti thousynde of lengthe, bi the departyng of the seyntuarie, to al the hous of Israel.", "rotherham": "And, the possession of the city, shall ye give, five thousand, in breadth, and in length, five and twenty thousand answering to the heave-offering of the holy portion,—for all the house of Israel, shall it be.", "darby": "And ye shall appoint the possession of the city five thousand in breadth, and five and twenty thousand in length, alongside of the holy heave-offering: it shall be for the whole house of Israel.", "twenty": "", "jps": "And ye shall appoint the possession of the city five thousand broad, and five and twenty thousand long, side by side with the offering of the holy portion; it shall be for the whole house of Israel.", "acv": "And ye shall appoint the possession of the city five thousand broad, and twenty-five thousand long, side by side with the oblation of the holy portion. It shall be for the whole house of Israel.", "anderson": "", "haweis": "", "noyes": "And ye shall appoint the possession of the city five thousand in breadth, and five and twenty thousand in length, over against the oblation of the holy portion; it shall be for all the house of Israel.", "webster": "And ye shall appoint the possession of the city five thousand broad, and five and twenty thousand long, over against the oblation of the holy [portion]: it shall be for the whole house of Israel.", "vulgate": "et possessionem civitatis dabitis quinque milia latitudinis et longitudinis viginti quinque milia secundum separationem sanctuarii omni domui Israhel;", "brenton": "And ye shall appoint for the possession of the city five thousand in breadth, and in length twenty-five thousand: after the manner of the first-fruits of the holy portion, they shall be for all the house of Israel."}}, {"v": 7, "ref": "45:7", "o": "וְ/לַ/נָּשִׂ֡יא מִ/זֶּ֣ה וּ/מִ/זֶּה֩ לִ/תְרוּמַ֨ת הַ/קֹּ֜דֶשׁ וְ/לַ/אֲחֻזַּ֣ת הָ/עִ֗יר אֶל פְּנֵ֤י תְרֽוּמַת הַ/קֹּ֨דֶשׁ֙ וְ/אֶל פְּנֵי֙ אֲחֻזַּ֣ת הָ/עִ֔יר מִ/פְּאַת יָ֣ם יָ֔מָּ/ה וּ/מִ/פְּאַת קֵ֖דְמָ/ה קָדִ֑ימָ/ה וְ/אֹ֗רֶךְ לְ/עֻמּוֹת֙ אַחַ֣ד הַ/חֲלָקִ֔ים מִ/גְּב֥וּל יָ֖ם אֶל גְּב֥וּל קָדִֽימָ/ה", "en": {"kjv": "And a portion shall be for the prince on the one side and on the other side of the oblation of the holy portion, and of the possession of the city, before the oblation of the holy portion, and before the possession of the city, from the west side westward, and from the east side eastward: and the length shall be over against one of the portions, from the west border unto the east border.", "web": "What is for the prince shall be on the one side and on the other side of the holy offering and of the possession of the city, in front of the holy offering and in front of the possession of the city, on the west side westward, and on the east side eastward; and in length answerable to one of the portions, from the west border to the east border.", "bsb": "Now the prince will have the area bordering each side of the area formed by the holy district and the property of the city, extending westward from the western side and eastward from the eastern side, running lengthwise from the western boundary to the eastern boundary and parallel to one of the tribal portions.", "asv": "And whatsoever is for the prince shall be on the one side and on the other side of the holy oblation and of the possession of the city, in front of the holy oblation and in front of the possession of the city, on the west side westward, and on the east side eastward; and in length answerable unto one of the portions, from the west border unto the east border.", "ylt": "As to the prince, on this side, and on that side, of the heave-offering of the holy place, and of the possession of the city, at the front of the heave-offering of the holy place, and at the front of the possession of the city, from the west corner westward, and from the east corner eastward--and the length is over-against one of the portions from the west border unto the east border--", "dra": "For the prince also on the one side and on the other side, according to the separation of the sanctuary, and according to the possession of the city, over against the separation of the sanctuary, and over against the possession of the city: from the side of the sea even to the sea, and from the side of the east even to the east. And the length according to every part from the west border to the east border.", "bbe": "And for the ruler there is to be a part on one side and on the other side of the holy offering and of the property of the town, in front of the holy offering and in front of the property of the town on the west of it and on the east: measured in the same line as one of the parts of the land, from its limit on the west to its limit on the east of the land.", "geneva": "And a portion shalbe for the prince on ye one side, and on that side of the oblation of the holy portion, and of the possession of the citie, euen before the oblation of the holy portion, and before the possession of the citie from the West corner Westward, and from the East corner Eastward, and the length shalbe by one of the portions from the West border vnto the East border.", "wycliffe": "And ye schulen yyue a porcioun to the prince on this side and on that side, bisidis the departyng of the seyntuarie, and bisidis the possessioun of the citee, ayens the face of departynge of seyntuarie, and ayens the face of possessioun of the citee; fro the side of the se til to the see, and fro the side of the eest `til to the eest, schal be of the possessioun of the prince. Forsothe the lengthe bi ech of the partis, fro the west ende til to the eest ende of the lond,", "rotherham": "And to the prince—on his side and on that, shall belong [a portion] of the heave-offering of the holy portion and of the possession of the city, facing the heave-offering of the holy portion and facing the possession of the city, on the west side westward and on the east side eastward,—and in length, answering to one of the portions, from the west boundary to the east boundary,", "darby": "And the prince shall have [his portion] on the one side and on the other side of the holy heave-offering and of the possession of the city, over against the holy heave-offering, and over against the possession of the city, from the west side westward, and from the east side eastward; and in length answering to one of the portions [of the tribes] from the west border unto the east border.", "twenty": "", "jps": "And for the prince, on the one side and on the other side of the holy offering and of the possession of the city, in front of the holy offering and in front of the possession of the city, on the west side westward, and on the east side eastward; and in length answerable unto one of the portions, from the west border unto the east border", "acv": "And whatever is for the ruler shall be on the one side and on the other side of the holy oblation and of the possession of the city, in front of the holy oblation and in front of the possession of the city, on the west side westward, and on the east side eastward, and in length answerable to one of the portions, from the west border to the east border.", "anderson": "", "haweis": "", "noyes": "And a portion shall be for the prince on this side and on that side of the oblation of the holy portion and of the possession of the city, before the oblation of the holy portion and before the possession of the city, from the west side westward, and from the east side eastward; and the length shall be over against every one of the portions, from the west border to the east border.", "webster": "And [a portion shall be] for the prince on the one side and on the other side of the oblation of the holy [portion], and of the possession of the city, before the oblation of the holy [portion], and before the possession of the city, from the west side westward, and from the east side eastward: and the length [shall be] over against one of the portions, from the west border to the east border.", "vulgate": "principi quoque hinc et inde in separationem sanctuarii et in possessionem civitatis contra faciem separationis sanctuarii et contra faciem possessionis urbis a latere maris usque ad mare et a latere orientis usque ad orientem longitudinem autem iuxta unamquamque partium a termino occidentali usque ad terminum orientalem;", "brenton": "And the prince shall have a portion out of this, and out of this there shall be a portion for the first-fruits of the sanctuary, and for the possession of the city, in front of the first-fruits of the sanctuary, and in front of the possession of the city westward, and from the western parts eastward: and the length shall be equal to one of the parts of the western borders, and the length shall be to the eastern borders of the land."}}, {"v": 8, "ref": "45:8", "o": "לָ/אָ֛רֶץ יִֽהְיֶה לּ֥/וֹ לַֽ/אֲחֻזָּ֖ה בְּ/יִשְׂרָאֵ֑ל וְ/לֹא יוֹנ֨וּ ע֤וֹד נְשִׂיאַ/י֙ אֶת עַמִּ֔/י וְ/הָ/אָ֛רֶץ יִתְּנ֥וּ לְ/בֵֽית יִשְׂרָאֵ֖ל לְ/שִׁבְטֵי/הֶֽם", "en": {"kjv": "In the land shall be his possession in Israel: and my princes shall no more oppress my people; and the rest of the land shall they give to the house of Israel according to their tribes.", "web": "In the land it shall be to him for a possession in Israel: and my princes shall no more oppress my people; but they shall give the land to the house of Israel according to their tribes.", "bsb": "This land will be his possession in Israel. And My princes will no longer oppress My people, but will give the rest of the land to the house of Israel according to their tribes.", "asv": "In the land it shall be to him for a possession in Israel: and my princes shall no more oppress my people; but they shall give the land to the house of Israel according to their tribes.", "ylt": "of the land there is to him for a possession in Israel, and My princes do not oppress any more My people, and the land they give to the house of Israel according to their tribes.", "dra": "He shall have a portion of the land in Israel: and the princes shall no more rob my people: but they shall give the land to the house of Israel according to their tribes:", "bbe": "And this will be his heritage in Israel: and my rulers will no longer be cruel masters to my people; but they will give the land as a heritage to the children of Israel by their tribes.", "geneva": "In this lande shalbe his possession in Israel: and my princes shall no more oppresse my people, and the rest of the land shall they giue to ye house of Israel, according to their tribes.", "wycliffe": "schal be possessioun to hym in Israel; and the princes schulen no more robbe my puple, but thei schulen yyue the lond to the hous of Israel, bi the lynagis of hem.", "rotherham": "Of the land, it shall be his for a possession in Israel,—and so my princes shall no more oppress my people, but the land itself, shall they give to the house of Israel, by their tribes.", "darby": "As land shall it be his for a possession in Israel; and my princes shall no more oppress my people; but they shall give the land to the house of Israel according to their tribes.", "twenty": "", "jps": "of the land; it shall be to him for a possession in Israel, and My princes shall no more wrong My people; but they shall give the land to the house of Israel according to their tribes.", "acv": "It shall be to him for a possession in the land in Israel. And my rulers shall no more oppress my people, but they shall give the land to the house of Israel according to their tribes.", "anderson": "", "haweis": "", "noyes": "As for the land, it shall be to him a possession in Israel, that my princes may no more oppress my people, but give the rest of the land to the house of Israel according to their tribes.", "webster": "In the land shall be his possession in Israel: and my princes shall no more oppress my people; and [the rest of] the land shall they give to the house of Israel according to their tribes.", "vulgate": "de terra erit ei possessio in Israhel et non depopulabuntur ultra principes populum meum sed terram dabunt domui Israhel secundum tribus eorum;", "brenton": "And he shall have it for a possession in Israel: and the princes of Israel shall no more oppress my people; but the house of Israel shall inherit the land according to their tribes."}}, {"v": 9, "ref": "45:9", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה רַב לָ/כֶם֙ נְשִׂיאֵ֣י יִשְׂרָאֵ֔ל חָמָ֤ס וָ/שֹׁד֙ הָסִ֔ירוּ וּ/מִשְׁפָּ֥ט וּ/צְדָקָ֖ה עֲשׂ֑וּ הָרִ֤ימוּ גְרֻשֹֽׁתֵי/כֶם֙ מֵ/עַ֣ל עַמִּ֔/י נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "Thus saith the Lord God; Let it suffice you, O princes of Israel: remove violence and spoil, and execute judgment and justice, take away your exactions from my people, saith the Lord God.", "web": "Thus says the Lord Yahweh: Let it suffice you, princes of Israel: remove violence and plunder, and execute justice and righteousness; dispossessing my people, says the Lord Yahweh.", "bsb": "For this is what the Lord GOD says: ‘Enough, O princes of Israel! Cease your violence and oppression, and do what is just and right. Stop dispossessing My people, declares the Lord GOD.’", "asv": "Thus saith the Lord Jehovah: Let it suffice you, O princes of Israel: remove violence and spoil, and execute justice and righteousness; take away your exactions from my people, saith the Lord Jehovah.", "ylt": "`Thus said the Lord Jehovah: Enough to you--princes of Israel; violence and spoil turn aside, and judgment and righteousness do; lift up your exactions from off My people--an affirmation of the Lord Jehovah.", "dra": "Thus saith the Lord God: Let it suffice you, O princes of Israel: cease from iniquity and robberies, and execute judgment and justice, separate your confines from my people, saith the Lord God.", "bbe": "This is what the Lord has said: Let this be enough for you, O rulers of Israel: let there be an end of violent behaviour and wasting; do what is right, judging uprightly; let there be no more driving out of my people, says the Lord.", "geneva": "Thus saith the Lord God, Let it suffice you, O princes of Israel: leaue off crueltie and oppression, and execute iudgment and iustice: take away your exactions from my people, sayth the Lord God.", "wycliffe": "The Lord God seith these thingis, O! princes of Israel, suffice it to you, leue ye wickidnesse `and raueyns, and do ye doom and riytfulnesse; departe ye youre niy coostis fro my puple, seith the Lord God.", "rotherham": "Thus saith My Lord Yahweh, Let it more than suffice you O princes of Israel, Violence and spoil, remove ye And justice and righteousness, execute,— Lift off your acts of expulsion from upon my people, Urgeth My Lord Yahweh.", "darby": "Thus saith the Lord Jehovah: Let it suffice you, princes of Israel! Put away violence and spoil, and execute judgment and justice; take off your exactions from my people, saith the Lord Jehovah.", "twenty": "", "jps": "Thus saith the L-rd GOD: Let it suffice you, O princes of Israel; remove violence and spoil, and execute justice and righteousness; take away your exactions from My people, saith the L-rd GOD.", "acv": "Thus says the lord Jehovah: Let it suffice you, O rulers of Israel. Remove violence and spoil, and execute justice and righteousness. Take away your exactions from my people, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: Let it suffice you, O princes of Israel! Remove violence and spoil, and execute judgment and justice, and cease from your expulsions of my people, saith the Lord Jehovah.", "webster": "Thus saith the Lord GOD; Let it suffice you, O princes of Israel: remove violence and spoil, and execute judgment and justice, take away your exactions from my people, saith the Lord GOD.", "vulgate": "haec dicit Dominus Deus sufficiat vobis principes Israhel iniquitatem et rapinas intermittite et iudicium et iustitiam facite separate confinia vestra a populo meo ait Dominus Deus;", "brenton": "Thus saith the Lord God; Let it suffice you, ye princes of Israel: remove injustice and misery, execute judgment and justice; take away oppression from my people, saith the Lord God."}}, {"v": 10, "ref": "45:10", "o": "מֹֽאזְנֵי צֶ֧דֶק וְ/אֵֽיפַת צֶ֛דֶק וּ/בַת צֶ֖דֶק יְהִ֥י לָ/כֶֽם", "en": {"kjv": "Ye shall have just balances, and a just ephah, and a just bath.", "web": "You shall have just balances, and a just ephah, and a just bath.", "bsb": "You must use honest scales, a just ephah, and a just bath.", "asv": "Ye shall have just balances, and a just ephah, and a just bath.", "ylt": "Just balances, and a just ephah, and a just bath--ye have.", "dra": "You shall have just balances, and a just ephi, and a just bate.", "bbe": "Have true scales and a true ephah and a true bath.", "geneva": "Ye shall haue iust balances, and a true Ephah, and a true Bath.", "wycliffe": "A iust balaunce, and a iust mesure clepid ephi, and a iust mesure clepid bathus, schulen be to you.", "rotherham": "Balances of righteousness, and an ephah of righteousness, and A bath of righteousness, have ye:", "darby": "Ye shall have just balances, and a just ephah, and a just bath.", "twenty": "", "jps": "Ye shall have just balances, and a just ephah, and a just bath.", "acv": "Ye shall have just balances, and a just ephah, and a just bath.", "anderson": "", "haweis": "", "noyes": "Ye shall have just balances, and a just ephah, and a just bath.", "webster": "Ye shall have just balances, and a just ephah, and a just bath.", "vulgate": "statera iusta et oephi iustum et batus iustus erit vobis;", "brenton": "Ye shall have a just balance, and a just measure, and a just choenix for measure."}}, {"v": 11, "ref": "45:11", "o": "הָ/אֵיפָ֣ה וְ/הַ/בַּ֗ת תֹּ֤כֶן אֶחָד֙ יִֽהְיֶ֔ה לָ/שֵׂ֕את מַעְשַׂ֥ר הַ/חֹ֖מֶר הַ/בָּ֑ת וַ/עֲשִׂירִ֤ת הַ/חֹ֨מֶר֙ הָֽ/אֵיפָ֔ה אֶל הַ/חֹ֖מֶר יִהְיֶ֥ה מַתְכֻּנְתּֽ/וֹ", "en": {"kjv": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of an homer, and the ephah the tenth part of an homer: the measure thereof shall be after the homer.", "web": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer: its measure shall be after the homer.", "bsb": "The ephah and the bath shall be the same quantity so that the bath will contain a tenth of a homer, and the ephah a tenth of a homer; the homer will be the standard measure for both.", "asv": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer: the measure thereof shall be after the homer.", "ylt": "The ephah and the bath is of one measure, for the bath to bear a tenth of the homer, and the ephah a tenth of the homer: according to the homer is its measurement.", "dra": "The ephi and the bate shall be equal, and of one measure: that the bate may contain the tenth part of a core, and the ephi the tenth part of a core: their weight shall be equal according to the measure of a core.", "bbe": "The ephah and the bath are to be of the same measure, so that the bath is equal to a tenth of a homer, and the ephah to a tenth of a homer: the unit of measure is to be a homer.", "geneva": "The Ephah and the Bath shalbe equall: a Bath shall conteyne the tenth part of an Homer, and an Ephah the tenth part of an Homer: the equalitie thereof shalbe after the Homer.", "wycliffe": "Ephi and bathus schulen be euene, and of o mesure, that bathus take the tenthe part of the mesure clepid corus, and that ephi take the tenthe part of the mesure corus; bi the mesure of corus schal be euene weiynge of tho.", "rotherham": "the ephah and the bath of one fixed measure, shall be, to contain the tenth of a homer, the bath,—and the tenth of a homer, the ephah, unto the homer, shall be the proportion thereof;", "darby": "The ephah and the bath shall be of one measure, so that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer: the measure thereof shall be according to the homer.", "twenty": "", "jps": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer; the measure thereof shall be after the homer.", "acv": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer. The measure of it shall be according to the homer.", "anderson": "", "haweis": "", "noyes": "The ephah and the bath shall be of one measure; that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer; the measure thereof shall be according to the homer.", "webster": "The ephah and the bath shall be of one measure, that the bath may contain the tenth part of a homer, and the ephah the tenth part of a homer: the measure of it shall be after the homer.", "vulgate": "oephi et batus aequalia et unius mensurae erunt ut capiat decimam partem chori batus et decimam partem chori oephi iuxta mensuram chori erit aequa libratio eorum;", "brenton": "And in like manner there shall be one choenix as a measure of capacity; the tenth of the gomor shall be the choenix, and the tenth of the gomor shall be in fair proportion to the gomor."}}, {"v": 12, "ref": "45:12", "o": "וְ/הַ/שֶּׁ֖קֶל עֶשְׂרִ֣ים גֵּרָ֑ה עֶשְׂרִ֨ים שְׁקָלִ֜ים חֲמִשָּׁ֧ה וְ/עֶשְׂרִ֣ים שְׁקָלִ֗ים עֲשָׂרָ֤ה וַ/חֲמִשָּׁה֙ שֶׁ֔קֶל הַ/מָּנֶ֖ה יִֽהְיֶ֥ה לָ/כֶֽם", "en": {"kjv": "And the shekel shall be twenty gerahs: twenty shekels, five and twenty shekels, fifteen shekels, shall be your maneh.", "web": "The shekel shall be twenty gerahs. Twenty shekels plus twenty-five shekels plus fifteen shekels shall be your mina.", "bsb": "The shekel will consist of twenty gerahs. Twenty shekels plus twenty-five shekels plus fifteen shekels will equal one mina.", "asv": "And the shekel shall be twenty gerahs; twenty shekels, five and twenty shekels, fifteen shekels, shall be your maneh.", "ylt": "And, the shekel is twenty gerah: twenty shekels, five and twenty shekels, fifteen shekels--is your maneh.", "dra": "And the sicle hath twenty obols. Now twenty sicles, and five and twenty sicles, and fifteen sicles, make a mna,", "bbe": "And the shekel is to be twenty gerahs: five shekels are five, and ten shekels are ten, and your maneh is to be fifty shekels", "geneva": "And the shekel shalbe twentie gerahs, and twentie shekels, and fiue and twentie shekels and fifteene shekels shalbe your Maneh.", "wycliffe": "Forsothe a sicle schal haue twenti halpens; certis twenti siclis, and fyue and twenti siclis, and fiftene siclis maken a besaunt.", "rotherham": "and the shekel shall be twenty gerahs,—twenty shekels five and twenty shekels and fifteen shekels, the weight shall be to you.", "darby": "And the shekel shall be twenty gerahs; twenty shekels, five and twenty shekels, fifteen shekels, shall be your maneh.", "twenty": "", "jps": "And the shekel shall be twenty gerahs; twenty shekels, five and twenty shekels, ten, and five shekels, shall be your maneh.", "acv": "And the shekel shall be twenty gerahs. Twenty shekels, twenty-five shekels, fifteen shekels, shall be your maneh.", "anderson": "", "haweis": "", "noyes": "And the shekel shall be twenty gerahs; twenty shekels, five and twenty shekels, and fifteen shekels shall be to you one maneh.", "webster": "And the shekel [shall be] twenty gerahs: twenty shekels, five and twenty shekels, fifteen shekels, shall be your maneh.", "vulgate": "siclus autem viginti obolos habeat porro viginti sicli et viginti quinque sicli et quindecim sicli minam facient;", "brenton": "And the weights shall be twenty oboli, your pound shall be five shekels, fifteen shekels and fifty shekels."}}, {"v": 13, "ref": "45:13", "o": "זֹ֥את הַ/תְּרוּמָ֖ה אֲשֶׁ֣ר תָּרִ֑ימוּ שִׁשִּׁ֤ית הָֽ/אֵיפָה֙ מֵ/חֹ֣מֶר הַֽ/חִטִּ֔ים וְ/שִׁשִּׁיתֶם֙ הָֽ/אֵיפָ֔ה מֵ/חֹ֖מֶר הַ/שְּׂעֹרִֽים", "en": {"kjv": "This is the oblation that ye shall offer; the sixth part of an ephah of an homer of wheat, and ye shall give the sixth part of an ephah of an homer of barley:", "web": "This is the offering that you shall offer: the sixth part of an ephah from a homer of wheat; and you shall give the sixth part of an ephah from a homer of barley;", "bsb": "This is the contribution you are to offer: a sixth of an ephah from each homer of wheat, and a sixth of an ephah from each homer of barley.", "asv": "This is the oblation that ye shall offer: the sixth part of an ephah from a homer of wheat; and ye shall give the sixth part of an ephah from a homer of barley;", "ylt": "`This is the heave-offering that ye lift up; a sixth part of the ephah of a homer of wheat, also ye have given a sixth part of the ephah of a homer of barley,", "dra": "And these are the firstfruits, which you shall take: the sixth part of an ephi of a core of wheat, and the sixth part of an ephi of a core of barley.", "bbe": "This is the offering you are to give: a sixth of an ephah out of a homer of wheat, and a sixth of an ephah out of a homer of barley;", "geneva": "This is the oblation that ye shall offer, ye sixt part of an Ephah of an Homer of wheat, and ye shall giue the sixt part of an Ephah of an Homer of barley.", "wycliffe": "And these ben the firste fruytis whiche ye schulen take awei; the sixte part of ephi of a corus of wheete, and the sixte part of ephi of a corus of barli.", "rotherham": "This is the heave-offering which ye shall offer up,- the sixth of an ephah, out of a homer of wheat, and the sixth of an ephah, out of a homer of barley;", "darby": "This is the heave-offering which ye shall offer: the sixth part of an ephah out of a homer of wheat, and ye shall give the sixth part of an ephah out of a homer of barley;", "twenty": "", "jps": "This is the offering that ye shall set apart: the sixth part of an ephah out of a homer of wheat, and ye shall give the sixth part of an ephah out of a homer of barley;", "acv": "This is the oblation that ye shall offer: The sixth part of an ephah from a homer of wheat, and ye shall give the sixth part of an ephah from a homer of barley,", "anderson": "", "haweis": "", "noyes": "This is the heave-offering which ye shall offer: the sixth part of an ephah out of a homer of wheat, and the sixth part of an ephah out of a homer of barley.", "webster": "This [is] the oblation that ye shall offer; the sixth part of an ephah of a homer of wheat, and ye shall give the sixth part of an ephah of a homer of barley;", "vulgate": "et haec sunt primitiae quas tolletis sextam partem oephi de choro frumenti et sextam partem oephi de choro hordei;", "brenton": "And these are the first-fruits which ye shall offer; a sixth part of a gomor of wheat, and the sixth part of it shall consist of an ephah of a core of barley."}}, {"v": 14, "ref": "45:14", "o": "וְ/חֹ֨ק הַ/שֶּׁ֜מֶן הַ/בַּ֣ת הַ/שֶּׁ֗מֶן מַעְשַׂ֤ר הַ/בַּת֙ מִן הַ/כֹּ֔ר עֲשֶׂ֥רֶת הַ/בַּתִּ֖ים חֹ֑מֶר כִּֽי עֲשֶׂ֥רֶת הַ/בַּתִּ֖ים חֹֽמֶר", "en": {"kjv": "Concerning the ordinance of oil, the bath of oil, ye shall offer the tenth part of a bath out of the cor, which is an homer of ten baths; for ten baths are an homer:", "web": "and the set portion of oil, of the bath of oil, the tenth part of a bath out of the cor, which is ten baths, even a homer; (for ten baths are a homer;)", "bsb": "The prescribed portion of oil, measured by the bath, is a tenth of a bath from each cor (a cor consists of ten baths or one homer, since ten baths are equivalent to a homer).", "asv": "and the set portion of oil, of the bath of oil, the tenth part of a bath out of the cor, which is ten baths, even a homer (for ten baths are a homer);", "ylt": "and the portion of oil, the bath of oil, a tenth part of the bath out of the cor, a homer of ten baths--for ten baths are a homer;", "dra": "The measure of oil also, a bate of oil is the tenth part of a core: and ten bates make a core: for ten bates fill a core.", "bbe": "And the fixed measure of oil is to be a tenth of a bath from the cor, for ten baths make up the cor;", "geneva": "Concerning ye ordinance of the oyle, euen of the Bath of oyle, ye shall offer the tenth part of a Bath out of ye Cor (ten Baths are an Homer: for ten Baths fill an Homer)", "wycliffe": "Also the mesure of oile; a bathus of oile is the tenthe part of corus, and ten bathus maken o corus; for ten bathus fillen o corus.", "rotherham": "And, the statutory portion of oil, shall be— per bath for oil—a tenth part of a bath out of a cor, which is ten baths even a homer; for, ten baths, are a homer.", "darby": "and the set portion of oil, by the bath of oil, the tenth part of a bath out of a cor, [which is] a homer of ten baths, for ten baths are a homer;", "twenty": "", "jps": "and the set portion of oil, the bath of oil, shall be the tithe of the bath out of the cor, which is ten baths, even a homer; for ten baths are a homer;", "acv": "and the set portion of oil, of the bath of oil, the tenth part of a bath out of the cor, which is ten baths, even a homer, (for ten baths are a homer),", "anderson": "", "haweis": "", "noyes": "And as for the statute concerning oil, the bath of oil, ye shall offer the tenth part of a bath out of a cor; a cor being ten baths; for a homer is ten baths.", "webster": "Concerning the ordinance of oil, the bath of oil, [ye shall offer] the tenth part of a bath out of the cor, [which is] a homer of ten baths: for ten baths [are] a homer:", "vulgate": "mensura quoque olei batus olei decima pars chori est et decem bati chorum faciunt quia decem bati implent chorum;", "brenton": "And ye shall give as the appointed measure of oil one bath of oil out of ten baths; for ten baths are a gomor."}}, {"v": 15, "ref": "45:15", "o": "וְ/שֶׂה אַחַ֨ת מִן הַ/צֹּ֤אן מִן הַ/מָּאתַ֨יִם֙ מִ/מַּשְׁקֵ֣ה יִשְׂרָאֵ֔ל לְ/מִנְחָ֖ה וּ/לְ/עוֹלָ֣ה וְ/לִ/שְׁלָמִ֑ים לְ/כַפֵּ֣ר עֲלֵי/הֶ֔ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And one lamb out of the flock, out of two hundred, out of the fat pastures of Israel; for a meat offering, and for a burnt offering, and for peace offerings, to make reconciliation for them, saith the Lord God.", "web": "and one lamb of the flock, out of two hundred, from the well-watered pastures of Israel—for a meal offering, and for a burnt offering, and for peace offerings, to make atonement for them, says the Lord Yahweh.", "bsb": "And one sheep shall be given from each flock of two hundred from the well-watered pastures of Israel. These are for the grain offerings, burnt offerings, and peace offerings, to make atonement for the people, declares the Lord GOD.", "asv": "and one lamb of the flock, out of two hundred, from the well-watered pastures of Israel;—for a meal-offering, and for a burnt-offering, and for peace-offerings, to make atonement for them, saith the Lord Jehovah.", "ylt": "and one lamb out of the flock, out of two hundred, out of the watered country of Israel, for a present, and for a burnt-offering, and for peace-offerings, to make atonement by them--an affirmation of the Lord Jehovah.", "dra": "And one ram out of a flock of two hundred, of those that Israel feedeth for sacrifice, and for holocausts, and for peace offerings, to make atonement for them, saith the Lord God.", "bbe": "And one lamb from the flock out of every two hundred, from all the families of Israel, for a meal offering and for a burned offering and for peace-offerings, to take away their sin, says the Lord.", "geneva": "And one lambe of two hundreth sheepe out of ye fat pastures of Israel for a meat offring, and for a burnt offring and for peace offrings, to make reconciliation for them, sayth the Lord God.", "wycliffe": "And `a ram of the floc of twei hundrid, of these whiche the men of Israel nurschen, in to sacrifice, and in to brent sacrifice, and in to pesible sacrifices, to clense for hem, seith the Lord God.", "rotherham": "And one lamb out of the flock out of two hundred out of the watered pastures of Israel, for a gift and for an ascending- sacrifice and for peace-offerings,— To put a propitiatory-covering over them, Declareth My Lord, Yahweh.", "darby": "and one lamb out of the flock, out of two hundred, from the well-watered pastures of Israel; — for an oblation, and for a burnt-offering, and for peace-offerings, to make atonement for them, saith the Lord Jehovah.", "twenty": "", "jps": "and one lamb of the flock, out of two hundred, from the well-watered pastures of Israel; for a meal-offering, and for a burnt-offering, and for peace-offerings, to make atonement for them, saith the L-rd GOD.", "acv": "and one lamb of the flock, out of two hundred, from the well-watered pastures of Israel, for a meal offering, and for a burnt offering, and for peace offerings, to make atonement for them, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And ye shall offer one lamb out of the flock, out of two hundred, from the watered pastures of Israel, for the flour-offering and for the burnt-offering, and for the thank-offerings, to make reconciliation for them, saith the Lord Jehovah.", "webster": "And one lamb out of the flock, out of two hundred, out of the fat pastures of Israel; for a meat-offering, and for a burnt-offering, and for peace-offerings, to make reconciliation for them, saith the Lord GOD.", "vulgate": "et arietem unum de grege ducentorum de his quae nutriunt Israhel in sacrificium et in holocaustum et in pacifica ad expiandum pro eis ait Dominus Deus;", "brenton": "And one sheep from the flock out of ten, as an oblation from all the tribes of Israel, for sacrifices, and for whole-burnt-offerings, and for peace-offerings, to make atonement for you, saith the Lord God."}}, {"v": 16, "ref": "45:16", "o": "כֹּ֚ל הָ/עָ֣ם הָ/אָ֔רֶץ יִהְי֖וּ אֶל הַ/תְּרוּמָ֣ה הַ/זֹּ֑את לַ/נָּשִׂ֖יא בְּ/יִשְׂרָאֵֽל", "en": {"kjv": "All the people of the land shall give this oblation for the prince in Israel.", "web": "All the people of the land shall give to this offering for the prince in Israel.", "bsb": "All the people of the land must participate in this contribution for the prince in Israel.", "asv": "All the people of the land shall give unto this oblation for the prince in Israel.", "ylt": "All the people of the land are at this heave-offering for the prince in Israel.", "dra": "All the people of the land shall be bound to these firstfruits for the prince in Israel.", "bbe": "All the people are to give this offering to the ruler.", "geneva": "All the people of the lande shall giue this oblation for the prince in Israel.", "wycliffe": "Al the puple of the lond schal be boundun in these firste fruytis to the prince of Israel.", "rotherham": "All the people of the land shall give to this heave-offering,—for the prince in Israel.", "darby": "All the people of the land shall be [held] to this heave-offering for the prince in Israel.", "twenty": "", "jps": "All the people of the land shall give this offering for the prince in Israel.", "acv": "All the people of the land shall give to this oblation for the ruler in Israel.", "anderson": "", "haweis": "", "noyes": "All the people of the land shall give this heave-offering for the prince in Israel.", "webster": "All the people of the land shall give this oblation for the prince in Israel.", "vulgate": "omnis populus terrae tenebitur primitiis his principi in Israhel;", "brenton": "And all the people shall give these first-fruits to the prince of Israel."}}, {"v": 17, "ref": "45:17", "o": "וְ/עַֽל הַ/נָּשִׂ֣יא יִהְיֶ֗ה הָ/עוֹל֣וֹת וְ/הַ/מִּנְחָה֮ וְ/הַ/נֵּסֶךְ֒ בַּ/חַגִּ֤ים וּ/בֶ/חֳדָשִׁים֙ וּ/בַ/שַּׁבָּת֔וֹת בְּ/כָֽל מוֹעֲדֵ֖י בֵּ֣ית יִשְׂרָאֵ֑ל הֽוּא יַעֲשֶׂ֞ה אֶת הַ/חַטָּ֣את וְ/אֶת הַ/מִּנְחָ֗ה וְ/אֶת הָֽ/עוֹלָה֙ וְ/אֶת הַ/שְּׁלָמִ֔ים לְ/כַפֵּ֖ר בְּעַ֥ד בֵּֽית יִשְׂרָאֵֽל", "en": {"kjv": "And it shall be the prince’s part to give burnt offerings, and meat offerings, and drink offerings, in the feasts, and in the new moons, and in the sabbaths, in all solemnities of the house of Israel: he shall prepare the sin offering, and the meat offering, and the burnt offering, and the peace offerings, to make reconciliation for the house of Israel.", "web": "It shall be the prince’s part to give the burnt offerings, and the meal offerings, and the drink offerings, in the feasts, and on the new moons, and on the Sabbaths, in all the appointed feasts of the house of Israel: he shall prepare the sin offering, and the meal offering, and the burnt offering, and the peace offerings, to make atonement for the house of Israel.", "bsb": "And it shall be the prince’s part to provide the burnt offerings, grain offerings, and drink offerings for the feasts, New Moons, and Sabbaths—for all the appointed feasts of the house of Israel. He will provide the sin offerings, grain offerings, burnt offerings, and peace offerings to make atonement for the house of Israel.", "asv": "And it shall be the prince’s part to give the burnt-offerings, and the meal-offerings, and the drink-offerings, in the feasts, and on the new moons, and on the sabbaths, in all the appointed feasts of the house of Israel: he shall prepare the sin-offering, and the meal-offering, and the burnt-offering, and the peace-offerings, to make atonement for the house of Israel.", "ylt": "And on the prince are the burnt-offerings, and the present, and the libation, in feasts, and in new moons, and in sabbaths, in all appointed times of the house of Israel: he doth make the sin-offering, and the present, and the burnt-offering, and the peace-offerings, to make atonement for the house of Israel.", "dra": "And the prince shall give the holocaust, and the sacrifice, and the libations on the feasts, and on the new moons, and on the sabbaths, and on all the solemnities of the house of Israel: he shall offer the sacrifice for sin, and the holocaust, and the peace offerings to make expiation for the house of Israel.", "bbe": "And the ruler will be responsible for the burned offering and the meal offering and the drink offering, at the feasts and the new moons and the Sabbaths, at all the fixed feasts of the children of Israel: he will give the sin-offering and meal offering and burned offering and the peace-offerings, to take away the sin of the children of Israel.", "geneva": "And it shalbe ye princes part to giue burnt offrings, and meat offrings, and drinke offrings in the solemne feasts and in the newe moones, and in the Sabbaths, and in all the hie feasts of the house of Israel: he shall prepare the sinne offring, and the meat offring, and the burnt offring, and the peace offrings to make reconciliation for the house of Israel.", "wycliffe": "And on the prince schulen be brent sacrifices, and sacrifice, and moiste sacrifices, in solempnytees, and in kalendis, ether bigynnyngis of monethis, and in sabatis, and in alle the solempnytees of the hous of Israel; he schal make sacrifice, for synne, and brent sacrifice, and pesible sacrifices, to clense for the hous of Israel.", "rotherham": "But on the prince himself, shall rest the ascending-sacrifices and the meal-offering, and the drink-offering, on the festivals, and on the new moons, and on the sabbaths, in all the appointed meetings of the house of Israel,—he, shall offer the sin-bearer. and the meal-offering, and the ascending sacrifice, and the peace-offerings, To put a propitiatory-covering about the house of Israel.", "darby": "And it shall be the prince's part [to supply] the burnt-offerings, and the oblation, and the drink-offering, at the feasts, and at the new moons, and on the sabbaths, in all the solemnities of the house of Israel: it is he that shall prepare the sin-offering, and the oblation, and the burnt-offering, and the peace-offerings, to make atonement for the house of Israel.", "twenty": "", "jps": "And it shall be the prince's part to give the burnt-offerings, and the meal-offerings, and the drink-offerings, in the feasts, and in the new moons, and in the sabbaths, in all the appointed seasons of the house of Israel; he shall prepare the sin-offering, and the meal-offering, and the burnt-offering, and the peace-offerings, to make atonement for the house of Israel.", "acv": "And it shall be the ruler's part to give the burnt offerings, and the meal offerings, and the drink offerings, in the feasts, and on the new moons, and on the sabbaths, in all the appointed feasts of the house of Israel. He shall prepare the sin offering, and the meal offering, and the burnt offering, and the peace offerings, to make atonement for the house of Israel.", "anderson": "", "haweis": "", "noyes": "And it shall be the duty of the prince to give burnt-offerings, and flour-offerings, and drink-offerings, in the feasts, and in the new moons, and in the sabbaths, and in all the solemn assemblies of the house of Israel; he shall present the sin-offering, and the flour-offering, and the burnt-offering, and the peace-offerings, to make reconciliation for the house of Israel.", "webster": "And it shall be the prince's part [to give] burnt-offerings, and meat-offerings, and drink-offerings, in the feasts, and in the new moons, and in the sabbaths, in all solemnities of the house of Israel: he shall prepare the sin-offering, and the meat-offering, and the burnt-offering, and the peace-offerings, to make reconciliation for the house of Israel.", "vulgate": "et super principem erunt holocausta et sacrificium et libamina in sollemnitatibus et in kalendis et in sabbatis in universis sollemnitatibus domus Israhel ipse faciat pro peccato sacrificium et holocaustum et pacifica ad expiandum pro domo Israhel;", "brenton": "And through the prince shall be offered the whole-burnt-offerings and the meat-offerings, and the drink-offerings in the feasts, and at the new moons, and on the sabbaths; and in all the feasts of the house of Israel: he shall offer the sin-offerings, and the meat-offering, and the whole-burnt-offerings, and the peace-offerings, to make atonement for the house of Israel."}}, {"v": 18, "ref": "45:18", "o": "כֹּה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ בָּֽ/רִאשׁוֹן֙ בְּ/אֶחָ֣ד לַ/חֹ֔דֶשׁ תִּקַּ֥ח פַּר בֶּן בָּקָ֖ר תָּמִ֑ים וְ/חִטֵּאתָ֖ אֶת הַ/מִּקְדָּֽשׁ", "en": {"kjv": "Thus saith the Lord God; In the first month, in the first day of the month, thou shalt take a young bullock without blemish, and cleanse the sanctuary:", "web": "Thus says the Lord Yahweh: In the first month, in the first day of the month, you shall take a young bull without defect; and you shall cleanse the sanctuary.", "bsb": "This is what the Lord GOD says: ‘On the first day of the first month you are to take a young bull without blemish and purify the sanctuary.", "asv": "Thus saith the Lord Jehovah: In the first month, in the first day of the month, thou shalt take a young bullock without blemish; and thou shalt cleanse the sanctuary.", "ylt": "`Thus said the Lord Jehovah: In the first month , in the first of the month, thou dost take a bullock, a son of the herd, a perfect one, and hast cleansed the sanctuary:", "dra": "Thus saith the Lord God: In the first month, the first of the month, thou shalt take a calf of the herd without blemish, and thou shalt expiate the sanctuary.", "bbe": "This is what the Lord has said: In the first month, on the first day of the month, you are to take a young ox without any mark on him, and you are to make the holy place clean.", "geneva": "Thus sayth the Lord God, In the first moneth, in the first day of the moneth, thou shalt take a yong bullocke without blemish and clense the Sanctuarie.", "wycliffe": "The Lord God seith these thingis, In the firste moneth, in the firste dai of the monethe, thou schalt take a calf with out wem of the drooue, and thou schalt clense the seyntuarie.", "rotherham": "Thus saith My Lord. Yahweh, In the first month on the first day of the month, shalt thou take a young bullock without defect, —and shalt cleanse the sanctuary from sin;", "darby": "Thus saith the Lord Jehovah: In the first [month], on the first of the month, thou shalt take a young bullock, without blemish, and thou shalt purge the sanctuary.", "twenty": "", "jps": "Thus saith the L-rd GOD: In the first month, in the first day of the month, thou shalt take a young bullock without blemish; and thou shalt purify the sanctuary.", "acv": "Thus says the lord Jehovah: In the first month, in the first day of the month, thou shall take a young bullock without blemish, and thou shall cleanse the sanctuary.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: In the first month, on the first day of the month, thou shalt take a young bullock without blemish, and shalt cleanse the sanctuary.", "webster": "Thus saith the Lord GOD; In the first [month], in the first [day] of the month, thou shalt take a young bullock without blemish, and cleanse the sanctuary:", "vulgate": "haec dicit Dominus Deus in primo mense una mensis sumes vitulum de armento inmaculatum et expiabis sanctuarium;", "brenton": "Thus saith the Lord God; In the first month, on the first day of the month, ye shall take a calf without blemish out of the herd, to make atonement for the holy place."}}, {"v": 19, "ref": "45:19", "o": "וְ/לָקַ֨ח הַ/כֹּהֵ֜ן מִ/דַּ֣ם הַ/חַטָּ֗את וְ/נָתַן֙ אֶל מְזוּזַ֣ת הַ/בַּ֔יִת וְ/אֶל אַרְבַּ֛ע פִּנּ֥וֹת הָ/עֲזָרָ֖ה לַ/מִּזְבֵּ֑חַ וְ/עַ֨ל מְזוּזַ֔ת שַׁ֖עַר הֶ/חָצֵ֥ר הַ/פְּנִימִֽית", "en": {"kjv": "And the priest shall take of the blood of the sin offering, and put it upon the posts of the house, and upon the four corners of the settle of the altar, and upon the posts of the gate of the inner court.", "web": "The priest shall take of the blood of the sin offering, and put it on the door posts of the house, and on the four corners of the ledge of the altar, and on the posts of the gate of the inner court.", "bsb": "And the priest is to take some of the blood from the sin offering and put it on the doorposts of the temple, on the four corners of the ledge of the altar, and on the gateposts of the inner court.", "asv": "And the priest shall take of the blood of the sin-offering, and put it upon the door-posts of the house, and upon the four corners of the ledge of the altar, and upon the posts of the gate of the inner court.", "ylt": "and the priest hath taken of the blood of the sin offering, and hath put on the door-post of the house, and on the four corners of the border of the altar, and on the post of the gate of the inner court.", "dra": "And the priest shall take of the blood of the sin offering: and he shall put it on the posts of the house, and on the four corners of the brim of the altar, and oil the posts of the gate of the inner court.", "bbe": "And the priest is to take some of the blood of the sin-offering and put it on the uprights at the sides of the doors of the house, and on the four angles of the shelf of the altar, and on the sides of the doorway of the inner square.", "geneva": "And the Priest shall take of the blood of the sinne offring, and put it vpon the posts of the house, and vpon the foure corners of the frame of the altar, and vpon the postes of the gate of the inner court.", "wycliffe": "And the preest schal take of the blood of the beeste, that schal be for synne; and he schal putte in the postis of the hous, and in foure corneris of the heiythe of the auter, and in the postis of the yate of the ynnere halle.", "rotherham": "then shall the priest take of the blood of the sin-bearer and put upon the door-posts of the house, and upon the four corners of the ledge of the altar and upon the door-posts of the gate of the inner court.", "darby": "And the priest shall take of the blood of the sin-offering, and put it upon the posts of the house, and upon the four corners of the settle of the altar, and upon the posts of the gate of the inner court.", "twenty": "", "jps": "And the priest shall take of the blood of the sin-offering, and put it upon the door-posts of the house, and upon the four corners of the settle of the altar, and upon the posts of the gate of the inner court.", "acv": "And the priest shall take of the blood of the sin offering, and put it upon the door-posts of the house, and upon the four corners of the ledge of the altar, and upon the posts of the gate of the inner court.", "anderson": "", "haweis": "", "noyes": "And the priest shall take of the blood of the sin-offering, and put it upon the posts of the house, and upon the four corners of the ledge of the altar, and upon the posts of the gate of the inner court.", "webster": "And the priest shall take of the blood of the sin-offering, and put [it] upon the posts of the house, and upon the four corners of the settle of the altar, and upon the posts of the gate of the inner court.", "vulgate": "et tollet sacerdos de sanguine quod erit pro peccato et ponet in postibus domus et in quattuor angulis crepidinis altaris et in postibus portae atrii interioris;", "brenton": "And the priest shall take of the blood of the atonement, and put it on the thresholds of the house, and upon the four corners of the temple, and upon the altar, and upon the thresholds of the gate of the inner court."}}, {"v": 20, "ref": "45:20", "o": "וְ/כֵ֤ן תַּֽעֲשֶׂה֙ בְּ/שִׁבְעָ֣ה בַ/חֹ֔דֶשׁ מֵ/אִ֥ישׁ שֹׁגֶ֖ה וּ/מִ/פֶּ֑תִי וְ/כִפַּרְתֶּ֖ם אֶת הַ/בָּֽיִת", "en": {"kjv": "And so thou shalt do the seventh day of the month for every one that erreth, and for him that is simple: so shall ye reconcile the house.", "web": "So you shall do on the seventh day of the month for everyone who errs, and for him who is simple: so you shall make atonement for the house.", "bsb": "You must do the same thing on the seventh day of the month for anyone who strays unintentionally or in ignorance. In this way you will make atonement for the temple.", "asv": "And so thou shalt do on the seventh day of the month for every one that erreth, and for him that is simple: so shall ye make atonement for the house.", "ylt": "And so thou dost do on the seventh of the month, because of each erring one, and because of the simple one--and ye have purified the house.", "dra": "And so shalt thou do in the seventh day of the month, for every one that hath been ignorant, and hath been deceived by error, and thou shalt make expiation for the house.", "bbe": "And this you are to do on the seventh day of the month for everyone who is in error and for the feeble-minded: you are to make the house free from sin.", "geneva": "And so shalt thou doe the seuenth day of the moneth, for euery one that hath erred and for him that is deceiued: so shall you reconcile the house.", "wycliffe": "And thus thou schalt do in the seuenthe dai of the monethe, for ech that knew not, and was disseyued bi errour, and thou schalt clense for the hous.", "rotherham": "And so shalt thou do in the seventh of the month, for any man that wavereth or is of feeble mind,—so shall ye cleanse the house by propitiation.", "darby": "So thou shalt do also on the seventh of the month for every one that erreth, and for the simple; and ye shall make atonement for the house.", "twenty": "", "jps": "And so thou shalt do on the seventh day of the month for every one that erreth, and for him that is simple; so shall ye make atonement for the house.", "acv": "And so thou shall do on the seventh day of the month for each one who errs, and for him who is simple. So shall ye make atonement for the house.", "anderson": "", "haweis": "", "noyes": "And so shalt thou do on the seventh day for him that hath transgressed through error or simplicity; so shall ye make reconciliation for the house.", "webster": "And so thou shalt do the seventh [day] of the month for every one that erreth, and for [him that is] simple: so shall ye reconcile the house.", "vulgate": "et sic facies in septima mensis pro unoquoque qui ignoravit et errore deceptus est et expiabitis pro domo;", "brenton": "And thus shalt thou do in the seventh month; on the first day of the month thou shalt take a rate from each one; and ye shall make atonement for the house."}}, {"v": 21, "ref": "45:21", "o": "בָּ֠/רִאשׁוֹן בְּ/אַרְבָּעָ֨ה עָשָׂ֥ר יוֹם֙ לַ/חֹ֔דֶשׁ יִהְיֶ֥ה לָ/כֶ֖ם הַ/פָּ֑סַח חָ֕ג שְׁבֻע֣וֹת יָמִ֔ים מַצּ֖וֹת יֵאָכֵֽל", "en": {"kjv": "In the first month, in the fourteenth day of the month, ye shall have the passover, a feast of seven days; unleavened bread shall be eaten.", "web": "In the first month, in the fourteenth day of the month, you shall have the Passover, a feast of seven days; unleavened bread shall be eaten.", "bsb": "On the fourteenth day of the first month you are to observe the Passover, a feast of seven days, during which unleavened bread shall be eaten.", "asv": "In the firstmonth, in the fourteenth day of the month, ye shall have the passover, a feast of seven days; unleavened bread shall be eaten.", "ylt": "`In the first month , in the fourteenth day of the month, ye have the passover, a feast of seven days, unleavened food is eaten.", "dra": "In the first month, the fourteenth day of the month, you shall observe the solemnity of the pasch: seven days unleavened bread shall be eaten.", "bbe": "In the first month, on the fourteenth day of the month, you are to have the Passover, a feast of seven days; unleavened bread is to be your food.", "geneva": "In the first moneth in the foureteenth day of the moneth, ye shall haue the Passeouer, a feast of seuen dayes, and ye shall eate vnleauened bread.", "wycliffe": "In the firste monethe, in the fourtenthe dai of the monethe, the solempnytee of pask schal be to you; therf looues schulen be etun bi seuene daies.", "rotherham": "In the first month on the fourteenth day of the month, shall ye have the passover, —a festival of seven days, unleavened cakes shall be, eaten;", "darby": "In the first [month], on the fourteenth day of the month, ye shall have the passover, a feast of seven days: unleavened bread shall be eaten.", "twenty": "", "jps": "In the first month, in the fourteenth day of the month, ye shall have the passover; a feast of seven days; unleavened bread shall be eaten.", "acv": "In the first month, in the fourteenth day of the month, ye shall have the Passover, a feast of seven days. Unleavened bread shall be eaten.", "anderson": "", "haweis": "", "noyes": "In the first month, on the fourteenth day of the month, ye shall have the passover, a feast of seven days; every one shall eat unleavened bread.", "webster": "In the first [month], in the fourteenth day of the month, ye shall have the passover, a feast of seven days; unleavened bread shall be eaten.", "vulgate": "in primo mense quartadecima die mensis erit vobis paschae sollemnitas septem diebus azyma comedentur;", "brenton": "And in the first month, on the fourteenth day of the month, ye shall have the feast of the passover; seven days shall ye eat unleavened bread."}}, {"v": 22, "ref": "45:22", "o": "וְ/עָשָׂ֤ה הַ/נָּשִׂיא֙ בַּ/יּ֣וֹם הַ/ה֔וּא בַּעֲד֕/וֹ וּ/בְעַ֖ד כָּל עַ֣ם הָ/אָ֑רֶץ פַּ֖ר חַטָּֽאת", "en": {"kjv": "And upon that day shall the prince prepare for himself and for all the people of the land a bullock for a sin offering.", "web": "On that day shall the prince prepare for himself and for all the people of the land a bull for a sin offering.", "bsb": "On that day the prince shall provide a bull as a sin offering for himself and for all the people of the land.", "asv": "And upon that day shall the prince prepare for himself and for all the people of the land a bullock for a sin-offering.", "ylt": "And the prince hath prepared on that day, for himself, and for all the people of the land, a bullock, a sin-offering.", "dra": "And the prince on that day shall offer for himself, and for all the people of the land, a calf for sin.", "bbe": "And on that day the ruler is to give for himself and for all the people of the land an ox for a sin-offering.", "geneva": "And vpon that day, shall the prince prepare for him selfe, and for all the people of the lande, a bullocke for a sinne offring.", "wycliffe": "And the prince schal make a calf for synne in that dai, for hym silf and for al the puple of the lond.", "rotherham": "therefore shall the prince offer, on that day, for himself, and for all the people of the land,—a bullock as a sin-bearer;", "darby": "And upon that day shall the prince offer for himself and for all the people of the land a bullock for a sin-offering.", "twenty": "", "jps": "And upon that day shall the prince prepare for himself and for all the people of the land a bullock for a sin-offering.", "acv": "And upon that day the ruler shall prepare for himself and for all the people of the land a bullock for a sin offering.", "anderson": "", "haweis": "", "noyes": "And upon that day shall the prince sacrifice for himself and for all the people of the land a bullock for a sin-offering.", "webster": "And upon that day shall the prince prepare for himself and for all the people of the land a bullock [for] a sin-offering.", "vulgate": "et faciet princeps in die illa pro se et pro universo populo terrae vitulum pro peccato;", "brenton": "And the prince shall offer in that day a calf for a sin-offering for himself, and the house, and for all the people of the land."}}, {"v": 23, "ref": "45:23", "o": "וְ/שִׁבְעַ֨ת יְמֵֽי הֶ/חָ֜ג יַעֲשֶׂ֧ה עוֹלָ֣ה לַֽ/יהוָ֗ה שִׁבְעַ֣ת פָּ֠רִים וְ/שִׁבְעַ֨ת אֵילִ֤ים תְּמִימִם֙ לַ/יּ֔וֹם שִׁבְעַ֖ת הַ/יָּמִ֑ים וְ/חַטָּ֕את שְׂעִ֥יר עִזִּ֖ים לַ/יּֽוֹם", "en": {"kjv": "And seven days of the feast he shall prepare a burnt offering to the Lord, seven bullocks and seven rams without blemish daily the seven days; and a kid of the goats daily for a sin offering.", "web": "The seven days of the feast he shall prepare a burnt offering to Yahweh, seven bulls and seven rams without defect daily the seven days; and a male goat daily for a sin offering.", "bsb": "Each day during the seven days of the feast, he shall provide seven bulls and seven rams without blemish as a burnt offering to the LORD, along with a male goat for a sin offering.", "asv": "And the seven days of the feast he shall prepare a burnt-offering to Jehovah, seven bullocks and seven rams without blemish daily the seven days; and a he-goat daily for a sin-offering.", "ylt": "And the seven days of the feast he prepareth a burnt-offering to Jehovah, seven bullocks, and seven rams, perfect ones, daily seven days, and a sin-offering, a kid of the goats, daily.", "dra": "And in the solemnity of the seven days he shall offer for a holocaust to the Lord, seven calves, and seven rams without blemish daily for seven days: and for sin a he goat daily.", "bbe": "And on the seven days of the feast he is to give a burned offering to the Lord, seven oxen and seven sheep without any mark on them, every day for seven days; and a he-goat every day for a sin-offering.", "geneva": "And in the seuen dayes of the feast he shall make a burnt offring to the Lord, euen of seuen bullockes, and seuen rammes without blemish dayly for seuen dayes, and an hee goate dayly for a sinne offring.", "wycliffe": "And in the solempnytee of seuene daies he schal make brent sacrifice to the Lord; he schal offre seuene caluys and seuene wetheris with out wem ech dai, bi seuene daies, and ech dai a buc of geet, for synne.", "rotherham": "and the seven days of the festival, shall he offer as an ascending-sacrifice to Yahweh seven bullocks and seven rams without defect, daily, for the seven days,—and as a sin- bearer, a young goat daily;", "darby": "And the seven days of the feast he shall offer a burnt-offering to Jehovah, seven bullocks and seven rams without blemish daily for the seven days; and a he-goat daily for a sin-offering.", "twenty": "", "jps": "And the seven days of the feast he shall prepare a burnt-offering to HaShem, seven bullocks and seven rams without blemish daily the seven days; and a he-goat daily for a sin-offering.", "acv": "And the seven days of the feast he shall prepare a burnt offering to Jehovah, seven bullocks and seven rams without blemish daily the seven days, and a he-goat daily for a sin offering.", "anderson": "", "haweis": "", "noyes": "And the seven days of the feast he shall sacrifice a burnt-offering to Jehovah, seven bullocks and seven rams without blemish daily the seven days; and a he-goat daily for a sin-offering.", "webster": "And seven days of the feast he shall prepare a burnt-offering to the LORD, seven bullocks and seven rams without blemish daily the seven days; and a kid of the goats daily [for] a sin-offering.", "vulgate": "et in septem dierum sollemnitate faciet holocaustum Domino septem vitulos et septem arietes inmaculatos cotidie septem diebus et pro peccato hircum caprarum cotidie;", "brenton": "And for the seven days of the feast he shall offer as whole-burnt-offerings to the Lord seven calves and seven rams without blemish daily for the seven days; and a kid of the goats daily for a sin-offering, and a meat-offering."}}, {"v": 24, "ref": "45:24", "o": "וּ/מִנְחָ֗ה אֵיפָ֥ה לַ/פָּ֛ר וְ/אֵיפָ֥ה לָ/אַ֖יִל יַֽעֲשֶׂ֑ה וְ/שֶׁ֖מֶן הִ֥ין לָ/אֵיפָֽה", "en": {"kjv": "And he shall prepare a meat offering of an ephah for a bullock, and an ephah for a ram, and an hin of oil for an ephah.", "web": "He shall prepare a meal offering, an ephah for a bull, and an ephah for a ram, and a hin of oil to an ephah.", "bsb": "He shall also provide as a grain offering an ephah for each bull and an ephah for each ram, along with a hin of olive oil for each ephah of grain.", "asv": "And he shall prepare a meal-offering, an ephah for a bullock, and an ephah for a ram, and a hin of oil to an ephah.", "ylt": "And a present of an ephah for a bullock, and an ephah for a ram, he doth prepare, and of oil a hin for an ephah.", "dra": "And he shall offer the sacrifice of an ephi for every calf, and an ephi for every ram: and a hin of oil for every ephi.", "bbe": "And he is to give a meal offering, an ephah for every ox and an ephah for every sheep and a hin of oil to every ephah.", "geneva": "And he shall prepare a meate offring of an Ephah for a bullocke, an Ephah for a ramme, and an Hin of oyle for an Ephah.", "wycliffe": "And he schal make the sacrifice of ephi by a calf, and of ephi by a wether, and of oile the mesure hyn, bi ech ephi.", "rotherham": "and a meal-offering of an ephah to each bullock. and an ephah to each ram, shall he offer,— and of oil a hin to an ephah.", "darby": "And he shall offer an oblation of an ephah for a bullock, and an ephah for a ram; and oil, a hin for an ephah.", "twenty": "", "jps": "And he shall prepare a meal-offering, an ephah for a bullock, and an ephah for a ram, and a hin of oil to an ephah.", "acv": "And he shall prepare a meal offering, an ephah for a bullock, and an ephah for a ram, and a hin of oil to an ephah.", "anderson": "", "haweis": "", "noyes": "And he shall present a flour-offering, an ephah for a bullock, and an ephah for a ram, and a hin of oil for an ephah.", "webster": "And he shall prepare a meat-offering of an ephah for a bullock, and an ephah for a ram, and a hin of oil for an ephah.", "vulgate": "et sacrificium oephi per vitulum et oephi per arietem faciet et olei hin per singula oephi;", "brenton": "And thou shalt prepare a cake for the calf, and cakes for the ram, and a hin of oil for the cake."}}, {"v": 25, "ref": "45:25", "o": "בַּ/שְּׁבִיעִ֡י בַּ/חֲמִשָּׁה֩ עָשָׂ֨ר י֤וֹם לַ/חֹ֨דֶשׁ֙ בֶּ/חָ֔ג יַעֲשֶׂ֥ה כָ/אֵ֖לֶּה שִׁבְעַ֣ת הַ/יָּמִ֑ים כַּֽ/חַטָּאת֙ כָּ/עֹלָ֔ה וְ/כַ/מִּנְחָ֖ה וְ/כַ/שָּֽׁמֶן", "en": {"kjv": "In the seventh month, in the fifteenth day of the month, shall he do the like in the feast of the seven days, according to the sin offering, according to the burnt offering, and according to the meat offering, and according to the oil.", "web": "In the seventh month, in the fifteenth day of the month, in the feast, shall he do the like the seven days; according to the sin offering, according to the burnt offering, and according to the meal offering, and according to the oil.", "bsb": "During the seven days of the feast that begins on the fifteenth day of the seventh month, he is to make the same provision for sin offerings, burnt offerings, grain offerings, and oil.’", "asv": "In the seventh month, in the fifteenth day of the month, in the feast, shall he do the like the seven days; according to the sin-offering, according to the burnt-offering, and according to the meal-offering, and according to the oil.", "ylt": "In the seventh month , in the fifteenth day of the month, in the feast, he doth according to these things seven days; as the sin-offering so the burnt-offering, and as the present so also the oil.", "dra": "In the seventh month, in the fifteenth day of the month, in the solemn feast, he shall do the like for the seven days: as well in regard to the sin offering, as to the holocaust, and the sacrifice, and the oil.", "bbe": "In the seventh month, on the fifteenth day of the month, at the feast, he is to give the same for seven days; the sin-offering, the burned offering, the meal offering, and the oil as before.", "geneva": "In the seuenth moneth, in the fifteenth day of the moneth, shall he do the like in the feast for seuen dayes, according to the sinne offring, according to the burnt offring, and according to the meate offring, and according to the oyle.", "wycliffe": "In the seuenthe monethe, in the fiftenthe dai of the monethe, in the solempnytee, he schal make as tho ben biforseid, bi seuene daies, as wel for synne as for brent sacrifice, and in sacrifice, and in oile.", "rotherham": "In the seventh month, on the fifteenth day of the month, throughout the festival, he shall offer like these seven days,—like the sin-bearer like the ascending-sacrifice, and like the meal offering, and like the oil.", "darby": "In the seventh [month], on the fifteenth day of the month, at the feast, shall he do the like seven days, according to the sin-offering, according to the burnt-offering, and according to the oblation, and according to the oil.", "twenty": "", "jps": "In the seventh month, in the fifteenth day of the month, in the feast, shall he do the like the seven days; to the sin-offering as well as the burnt-offering, and the meal-offering as well as the oil.", "acv": "In the seventh month, in the fifteenth day of the month, in the feast, he shall do the like the seven days, according to the sin offering, according to the burnt offering, and according to the meal offering, and according to the oil.", "anderson": "", "haweis": "", "noyes": "In the seventh month, on the fifteenth day of the month, shall he do the like, in the feast, seven days, according to the sin-offering, and the burnt-offering, and the flour-offering, and the oil.", "webster": "In the seventh [month], in the fifteenth day of the month, shall he do the like in the feast of the seven days, according to the sin-offering, according to the burnt-offering, and according to the meat-offering, and according to the oil.", "vulgate": "septimo mense quintadecima die mensis in sollemnitate faciet sicut supra dicta sunt per septem dies tam pro peccato quam pro holocausto et in sacrificio et in oleo;", "brenton": "And in the seventh month, on the fifteenth day of the month, thou shalt sacrifice in the feast in the same way seven days, as they sacrificed the sin-offerings, and the whole-burnt-offerings, and the freewill-offering, and the oil."}}]}, {"c": 46, "verses": [{"v": 1, "ref": "46:1", "o": "כֹּֽה אָמַר֮ אֲדֹנָ֣/י יְהוִה֒ שַׁ֜עַר הֶ/חָצֵ֤ר הַ/פְּנִימִית֙ הַ/פֹּנֶ֣ה קָדִ֔ים יִהְיֶ֣ה סָג֔וּר שֵׁ֖שֶׁת יְמֵ֣י הַֽ/מַּעֲשֶׂ֑ה וּ/בְ/י֤וֹם הַ/שַּׁבָּת֙ יִפָּתֵ֔חַ וּ/בְ/י֥וֹם הַ/חֹ֖דֶשׁ יִפָּתֵֽחַ", "en": {"kjv": "Thus saith the Lord God; The gate of the inner court that looketh toward the east shall be shut the six working days; but on the sabbath it shall be opened, and in the day of the new moon it shall be opened.", "web": "Thus says the Lord Yahweh: The gate of the inner court that looks toward the east shall be shut the six working days; but on the Sabbath day it shall be opened, and on the day of the new moon it shall be opened.", "bsb": "“This is what the Lord GOD says: ‘The gate of the inner court that faces east must be kept shut during the six days of work, but on the Sabbath day and on the day of the New Moon it shall be opened.", "asv": "Thus saith the Lord Jehovah: The gate of the inner court that looketh toward the east shall be shut the six working days; but on the sabbath day it shall be opened, and on the day of the new moon it shall be opened.", "ylt": "`Thus said the Lord Jehovah: The gate of the inner court that is looking eastward is shut the six days of work, and on the day of rest it is opened, and in the day of the new moon it is opened;", "dra": "Thus saith the Lord God: The gate of the inner court that looketh toward the east, shall be shut the six days, on which work is done; but on the sabbath day it shall be opened, yea and on the day of the new moon it shall be opened.", "bbe": "This is what the Lord has said: The doorway of the inner square looking to the east is to be shut on the six working days; but on the Sabbath it is to be open, and at the time of the new moon it is to be open.", "geneva": "Thus sayth the Lord God, The gate of the inner court, that turneth toward the East, shall be shut the sixe working dayes: but on the Sabbath it shalbe opened, and in the day of the newe moone it shalbe opened.", "wycliffe": "The Lord God seith these thingis, The yate of the ynnere halle, that biholdith to the eest, schal be closid bi sixe daies, in whiche werk is doon; for it schal be openid in the dai of sabat, but also it schal be openyd in the dai of kalendis.", "rotherham": "Thus saith My Lord Yahweh, the gate of the inner court which looketh toward the east shall be shut, the six days of work,—but on the sabbath-day, shall it be opened, and on the day of the new moon, shall it be opened.", "darby": "Thus saith the Lord Jehovah: The gate of the inner court that looketh toward the east shall be shut the six working-days; but on the sabbath-day it shall be opened, and on the day of the new moon it shall be opened.", "twenty": "", "jps": "Thus saith the L-rd GOD: The gate of the inner court that looketh toward the east shall be shut the six working days; but on the sabbath day it shall be opened, and in the day of the new moon it shall be opened.", "acv": "Thus says the lord Jehovah: The gate of the inner court that looks toward the east shall be shut the six working days, but on the sabbath day it shall be opened, and on the day of the new moon it shall be opened.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: The gate of the inner court, that looketh toward the east, shall be shut the six working-days; but on the sabbath it shall be opened, and on the day of the new moon it shall be opened.", "webster": "Thus saith the Lord GOD; The gate of the inner court that looketh towards the east shall be shut the six working days; but on the sabbath it shall be opened, and in the day of the new moon it shall be opened.", "vulgate": "haec dicit Dominus Deus porta atrii interioris quae respicit ad orientem erit clausa sex diebus in quibus opus fit die autem sabbati aperietur sed et in die kalendarum aperietur;", "brenton": "Thus saith the Lord God; The gate that is in the inner court, that looks eastward, shall be shut the six working days; but let it be opened on the sabbath-day, and it shall be opened on the day of the new moon."}}, {"v": 2, "ref": "46:2", "o": "וּ/בָ֣א הַ/נָּשִׂ֡יא דֶּרֶךְ֩ אוּלָ֨ם הַ/שַּׁ֜עַר מִ/ח֗וּץ וְ/עָמַד֙ עַל מְזוּזַ֣ת הַ/שַּׁ֔עַר וְ/עָשׂ֣וּ הַ/כֹּהֲנִ֗ים אֶת עֽוֹלָת/וֹ֙ וְ/אֶת שְׁלָמָ֔י/ו וְ/הִֽשְׁתַּחֲוָ֛ה עַל מִפְתַּ֥ן הַ/שַּׁ֖עַר וְ/יָצָ֑א וְ/הַ/שַּׁ֥עַר לֹֽא יִסָּגֵ֖ר עַד הָ/עָֽרֶב", "en": {"kjv": "And the prince shall enter by the way of the porch of that gate without, and shall stand by the post of the gate, and the priests shall prepare his burnt offering and his peace offerings, and he shall worship at the threshold of the gate: then he shall go forth; but the gate shall not be shut until the evening.", "web": "The prince shall enter by the way of the porch of the gate outside, and shall stand by the post of the gate; and the priests shall prepare his burnt offering and his peace offerings, and he shall worship at the threshold of the gate: then he shall go out; but the gate shall not be shut until the evening.", "bsb": "The prince is to enter from the outside through the portico of the gateway and stand by the gatepost, while the priests sacrifice his burnt offerings and peace offerings. He is to bow in worship at the threshold of the gate and then depart, but the gate must not be shut until evening.", "asv": "And the prince shall enter by the way of the porch of the gate without, and shall stand by the post of the gate; and the priests shall prepare his burnt-offering and his peace-offerings, and he shall worship at the threshold of the gate: then he shall go forth; but the gate shall not be shut until the evening.", "ylt": "and come in hath the prince the way of the porch of the gate at the outside, and he hath stood by the post of the gate, and the priests have made his burnt-offering, and his peace-offerings, and he hath bowed himself by the opening of the gate, and hath gone forth, and the gate is not shut till the evening.", "dra": "And the prince shall enter by the way of the porch of the gate from without, and he shall stand at the threshold of the gate: and the priests shall offer his holocaust, and his peace offerings: and he shall adore upon the threshold of the gate, and shall go out: but the gate shall not be shut till the evening.", "bbe": "And the ruler is to go in through the covered way of the outer doorway outside, and take his place by the pillar of the doorway, and the priests will make his burned offering and his peace-offerings and he will give worship at the doorstep of the doorway; then he will go out, and the door will not be shut till the evening.", "geneva": "And the prince shall enter by the way of the porch of that gate without, and shall stande by the post of the gate, and the Priests shall make his burnt offring, and his peace offrings, and he shall worship at the threshold of the gate: after, he shall go foorth, but the gate shall not be shut till the euening.", "wycliffe": "And the prince schal entre bi the weie of the porche of the yate withoutforth, and he schal stonde in the threisfold of the yate; and preestis schulen make the brent sacrifice of hym, and the pesible sacrifices of hym; and he schal worschipe on the threisfold of the yate, and he schal go out; forsothe the yate schal not be closid til to the euentid.", "rotherham": "The prince therefore shall enter by way of the porch of the gate without and shall stand by the post of the gate, and the priests shall offer his ascending-sacrifice and his peace offerings, and he shall bow down upon the threshold of the gate and then go forth, but the gate shall not be shut until the evening;", "darby": "And the prince shall enter by the way of the porch of [that] gate from without, and shall stand by the post of the gate, and the priests shall offer his burnt-offering and his peace-offerings, and he shall worship at the threshold of the gate, and shall go forth: but the gate shall not be shut until the evening.", "twenty": "", "jps": "And the prince shall enter by the way of the porch of the gate without, and shall stand by the post of the gate, and the priests shall prepare his burnt-offering and his peace-offerings, and he shall worship at the threshold of the gate; then he shall go forth; but the gate shall not be shut until the evening.", "acv": "And the ruler shall enter by the way of the porch of the gate outside, and shall stand by the post of the gate. And the priests shall prepare his burnt offering and his peace offerings, and he shall worship at the threshold of the gate. Then he shall go forth, but the gate shall not be shut until the evening.", "anderson": "", "haweis": "", "noyes": "And the prince shall enter by the way of the porch of the outer gate, and shall stand by the post of the gate, and the priests shall present his burnt-offerings, and his peace-offerings, and he shall worship at the threshold of the gate; then he shall go forth; but the gate shall not be shut until the evening.", "webster": "And the prince shall enter by the way of the porch of [that] gate without, and shall stand by the post of the gate, and the priest shall prepare his burnt-offering and his peace-offerings, and he shall worship at the threshhold of the gate: then he shall go forth; but the gate shall not be shut until the evening.", "vulgate": "et intrabit princeps per viam vestibuli portae de foris et stabit in limine portae et facient sacerdotes holocaustum eius et pacifica eius et adorabit super limen portae et egredietur porta autem non claudetur usque ad vesperam;", "brenton": "And the prince shall enter by the way of the porch of the inner gate, and shall stand at the entrance of the gate, and the priests shall prepare his whole-burnt-offerings and his peace-offerings, and he shall worship at the entrance of the gate: then shall he come forth; but the gate shall not be shut till evening."}}, {"v": 3, "ref": "46:3", "o": "וְ/הִשְׁתַּחֲו֣וּ עַם הָ/אָ֗רֶץ פֶּ֚תַח הַ/שַּׁ֣עַר הַ/ה֔וּא בַּ/שַּׁבָּת֖וֹת וּ/בֶ/חֳדָשִׁ֑ים לִ/פְנֵ֖י יְהוָֽה", "en": {"kjv": "Likewise the people of the land shall worship at the door of this gate before the Lord in the sabbaths and in the new moons.", "web": "The people of the land shall worship at the door of that gate before Yahweh on the Sabbaths and on the new moons.", "bsb": "On the Sabbaths and New Moons the people of the land are also to bow in worship before the LORD at the entrance to that gateway.", "asv": "And the people of the land shall worship at the door of that gate before Jehovah on the sabbaths and on the new moons.", "ylt": "And bowed themselves have the people of the land at the opening of that gate, on sabbaths, and on new moons, before Jehovah.", "dra": "And the people of the land shall adore at the door of that gate before the Lord on the sabbaths, and on the new moons.", "bbe": "And the people of the land are to give worship at the door of that doorway before the Lord on the Sabbaths and at the new moons.", "geneva": "Likewise the people of the lande shall worshippe at the entrie of this gate before the Lord on the Sabbaths, and in the newe moones.", "wycliffe": "And the puple of the lond schal worschipe at the dore of that yate, in sabatis, and in calendis, bifor the Lord.", "rotherham": "and the people of the land, shall bow down, at the entrance of that gate on the sabbaths and at the new moons,—before Yahweh.", "darby": "And the people of the land shall worship at the door of this gate before Jehovah on the sabbaths and on the new moons.", "twenty": "", "jps": "Likewise the people of the land shall worship at the door of that gate before HaShem in the sabbaths and in the new moons.", "acv": "And the people of the land shall worship at the door of that gate before Jehovah on the sabbaths and on the new moons.", "anderson": "", "haweis": "", "noyes": "Likewise the people of the land shall worship at the door of this gate before Jehovah on the sabbaths and on the new moons.", "webster": "Likewise the people of the land shall worship at the door of this gate before the LORD in the sabbaths and in the new moons.", "vulgate": "et adorabit populus terrae ad ostium portae illius in sabbatis et in kalendis coram Domino;", "brenton": "And the people of the land shall worship at the entrance of that gate, both on the sabbaths and at the new moons, before the Lord."}}, {"v": 4, "ref": "46:4", "o": "וְ/הָ֣/עֹלָ֔ה אֲשֶׁר יַקְרִ֥ב הַ/נָּשִׂ֖יא לַֽ/יהוָ֑ה בְּ/י֣וֹם הַ/שַּׁבָּ֗ת שִׁשָּׁ֧ה כְבָשִׂ֛ים תְּמִימִ֖ם וְ/אַ֥יִל תָּמִֽים", "en": {"kjv": "And the burnt offering that the prince shall offer unto the Lord in the sabbath day shall be six lambs without blemish, and a ram without blemish.", "web": "The burnt offering that the prince shall offer to Yahweh shall be on the Sabbath day six lambs without defect and a ram without defect;", "bsb": "The burnt offering that the prince presents to the LORD on the Sabbath day shall be six unblemished male lambs and an unblemished ram.", "asv": "And the burnt-offering that the prince shall offer unto Jehovah shall be on the sabbath day six lambs without blemish and a ram without blemish;", "ylt": "`And the burnt-offering that the prince bringeth near to Jehovah on the day of rest is six lambs, perfect ones, and a ram, a perfect one.", "dra": "And the holocaust that the prince shall offer to the Lord on the sabbath day, shall be six lambs without blemish, and a ram without blemish.", "bbe": "And the burned offering offered to the Lord by the ruler on the Sabbath day is to be six lambs without a mark on them and a male sheep without a mark;", "geneva": "And the burnt offring that the prince shall offer vnto the Lord on the Sabbath day, shalbe sixe lambs without blemish, and a ram without blemish.", "wycliffe": "Forsothe the prince schal offre this brent sacrifice to the Lord in the dai of sabat, sixe lambren with out wem, and a wether with out wem,", "rotherham": "And, the ascending-sacrifice which the prince shall bring near unto Yahweh, [shall be] on the sabbath day, six he-lambs without defect and a ram without defect;", "darby": "And the burnt-offering that the prince shall present unto Jehovah on the sabbath-day shall be six lambs without blemish, and a ram without blemish.", "twenty": "", "jps": "And the burnt-offering that the prince shall offer unto HaShem shall be in the sabbath day six lambs without blemish and a ram without blemish;", "acv": "And the burnt offering that the ruler shall offer to Jehovah shall be on the sabbath day six lambs without blemish and a ram without blemish,", "anderson": "", "haweis": "", "noyes": "And the burnt-offering, which the prince shall offer to Jehovah on the sabbath-day, shall be six lambs without blemish, and a ram without blemish.", "webster": "And the burnt-offering that the prince shall offer to the LORD in the sabbath day [shall be] six lambs without blemish, and a ram without blemish.", "vulgate": "holocaustum autem hoc offeret princeps Domino in die sabbati sex agnos inmaculatos et arietem inmaculatum;", "brenton": "And the prince shall offer whole-burnt-offerings to the Lord on the sabbath-day, six lambs without blemish, and a ram without blemish;"}}, {"v": 5, "ref": "46:5", "o": "וּ/מִנְחָה֙ אֵיפָ֣ה לָ/אַ֔יִל וְ/לַ/כְּבָשִׂ֥ים מִנְחָ֖ה מַתַּ֣ת יָד֑/וֹ וְ/שֶׁ֖מֶן הִ֥ין לָ/אֵיפָֽה", "en": {"kjv": "And the meat offering shall be an ephah for a ram, and the meat offering for the lambs as he shall be able to give, and an hin of oil to an ephah.", "web": "and the meal offering shall be an ephah for the ram, and the meal offering for the lambs as he is able to give, and a hin of oil to an ephah.", "bsb": "The grain offering with the ram shall be one ephah, and the grain offering with the lambs shall be as much as he is able, along with a hin of oil per ephah.", "asv": "and the meal-offering shall be an ephah for the ram, and the meal-offering for the lambs as he is able to give, and a hin of oil to an ephah.", "ylt": "And the present is an ephah for a ram, and for the lambs a present, the gift of his hand, and of oil a hin for an ephah.", "dra": "And the sacrifice of all ephi for a ram: but for the lambs what sacrifice his hand shall allow: and a hin of oil for every ephi.", "bbe": "And the meal offering is to be an ephah for the sheep, and for the lambs whatever he is able to give, and a hin of oil to an ephah.", "geneva": "And the meat offring shalbe an Ephah for a ram: and the meate offring for the lambs a gift of his hand, and an Hin of oyle to an Ephah.", "wycliffe": "and the sacrifice of ephi bi a wether; but in the lambren he schal offre the sacrifice which his hond schal yiue, and of oile the mesure hyn, bi ech ephi.", "rotherham": "and the meal-offering shall be an ephah to a ram, and to the he-lambs, the meal-offering shall be as one is able to give,— and of, a hin to an ephah.", "darby": "And the oblation shall be an ephah for a ram, and the oblation for the lambs as he shall be able to give; and oil, a hin for an ephah.", "twenty": "", "jps": "and the meal-offering shall be an ephah for the ram, and the meal-offering for the lambs as he is able to give, and a hin of oil to an ephah.", "acv": "and the meal offering shall be an ephah for the ram, and the meal offering for the lambs as he is able to give, and a hin of oil to an ephah.", "anderson": "", "haweis": "", "noyes": "And the flour-offering shall be an ephah for a ram; and the flour-offering for the lambs as much as he is disposed to give; and a hin of oil to an ephah.", "webster": "And the meat-offering [shall be] an ephah for a ram, and the meat-offering for the lambs as he shall be able to give, and a hin of oil to an ephah.", "vulgate": "et sacrificium oephi per arietem agnis autem sacrificium quod dederit manus eius et olei hin per singula oephi;", "brenton": "and a freewill-offering, a meat-offering for the ram, and a meat-offering for the lambs, the gift of his hand, and a hin of oil for the meat-offering."}}, {"v": 6, "ref": "46:6", "o": "וּ/בְ/י֣וֹם הַ/חֹ֔דֶשׁ פַּ֥ר בֶּן בָּקָ֖ר תְּמִימִ֑ם וְ/שֵׁ֧שֶׁת כְּבָשִׂ֛ם וָ/אַ֖יִל תְּמִימִ֥ם יִהְיֽוּ", "en": {"kjv": "And in the day of the new moon it shall be a young bullock without blemish, and six lambs, and a ram: they shall be without blemish.", "web": "On the day of the new moon it shall be a young bull without defect, and six lambs, and a ram; they shall be without defect:", "bsb": "On the day of the New Moon he shall offer a young, unblemished bull, six lambs, and a ram without blemish.", "asv": "And on the day of the new moon it shall be a young bullock without blemish, and six lambs, and a ram; they shall be without blemish:", "ylt": "And on the day of the new moon a bullock, a son of the herd, a perfect one, and six lambs and a ram, they are perfect.", "dra": "And on the day of the new moon a calf of the herd without blemish: and the six lambs, and the rams shall be without blemish.", "bbe": "And at the time of the new moon it is to be a young ox of the herd without a mark on him, and six lambs and a male sheep, all without a mark:", "geneva": "And in the day of the newe moone it shall be a yong bullocke without blemish, and sixe lambes and a ram: they shalbe without blemish.", "wycliffe": "But in the dai of calendis he schal offre a calf with out wem of the droue; and sixe lambren, and wetheris schulen be with out wem,", "rotherham": "But on the day of the new moon, a young bullock without defect, —and six he-lambs and a ram without defect, shall they be;", "darby": "And on the day of the new moon, a young bullock without blemish, and six lambs, and a ram: they shall be without blemish.", "twenty": "", "jps": "And in the day of the new moon it shall be a young bullock without blemish; and six lambs, and a ram; they shall be without blemish;", "acv": "And on the day of the new moon it shall be a young bullock without blemish, and six lambs, and a ram. They shall be without blemish.", "anderson": "", "haweis": "", "noyes": "And in the day of the new moon there shall be a young bullock without blemish, and six lambs and a ram; they shall be without blemish.", "webster": "And in the day of the new moon [it shall be] a young bullock without blemish, and six lambs, and a ram: they shall be without blemish.", "vulgate": "in die autem kalendarum vitulum de armento inmaculatum et sex agni et arietes inmaculati erunt;", "brenton": "And on the day of the new moon a calf without blemish, and six lambs, and there shall be a ram without blemish;"}}, {"v": 7, "ref": "46:7", "o": "וְ/אֵיפָ֨ה לַ/פָּ֜ר וְ/אֵיפָ֤ה לָ/אַ֨יִל֙ יַעֲשֶׂ֣ה מִנְחָ֔ה וְ/לַ֨/כְּבָשִׂ֔ים כַּ/אֲשֶׁ֥ר תַּשִּׂ֖יג יָד֑/וֹ וְ/שֶׁ֖מֶן הִ֥ין לָ/אֵיפָֽה", "en": {"kjv": "And he shall prepare a meat offering, an ephah for a bullock, and an ephah for a ram, and for the lambs according as his hand shall attain unto, and an hin of oil to an ephah.", "web": "and he shall prepare a meal offering, an ephah for the bull, and an ephah for the ram, and for the lambs according as he is able, and a hin of oil to an ephah.", "bsb": "He is to provide a grain offering of an ephah with the bull, an ephah with the ram, and as much as he is able with the lambs, along with a hin of oil per ephah.", "asv": "and he shall prepare a meal-offering, an ephah for the bullock, and an ephah for the ram, and for the lambs according as he is able, and a hin of oil to an ephah.", "ylt": "And with an ephah for a bullock, and an ephah for a ram, he prepareth a present, and for the lambs as his hand attaineth, and of oil a hin for an ephah.", "dra": "And he shall offer in sacrifice an ephi for calf, an ephi also for a ram: but for the lambs, as his hand shall find: and a hin of oil for every ephi.", "bbe": "And he is to give a meal offering, an ephah for the ox and an ephah for the sheep, and for the lambs whatever he is able to give, and a hin of oil to an ephah.", "geneva": "And he shall prepare a meat offring, euen an Ephah for a bullocke, and an Ephah for a ram, and for the lambes according as his hand shall bring, and an Hin of oyle to an Ephah.", "wycliffe": "and ephi bi a calf. Also he schal make the sacrifice ephi bi a wether; but of lambren as his hond fyndith, and of oile the mesure hyn, bi ech ephi.", "rotherham": "and an ephah to a bullock, and an ephah to a ram, shall he offer as a meal-offering, and for the he-lambs, just as his hand shall attain unto,—and of oil a hin to an ephah.", "darby": "And he shall offer an oblation, an ephah for the bullock, and an ephah for the ram, and for the lambs according to what his hand may attain unto; and oil, a hin for an ephah.", "twenty": "", "jps": "and he shall prepare a meal-offering, an ephah for the bullock, and an ephah for the ram, and for the lambs according as his means suffice, and a hin of oil to an ephah.", "acv": "And he shall prepare a meal offering, an ephah for the bullock, and an ephah for the ram, and for the lambs according as he is able, and a hin of oil to an ephah.", "anderson": "", "haweis": "", "noyes": "And he shall present, as a flour-offering, an ephah for a bullock, and an ephah for a ram, and for the lambs as much as he is able to give; and a hin of oil to an ephah.", "webster": "And he shall prepare a meat-offering, an ephah for a bullock, and an ephah for a ram, and for the lambs according as his hand shall be able, and a hin of oil to an ephah.", "vulgate": "et oephi per vitulum oephi quoque per arietem faciet sacrificium agnis autem sicut invenerit manus eius et olei hin per singula oephi;", "brenton": "and a meat-offering for the ram, and there shall be a meat-offering for the calf as a freewill-offering, and for the lambs, according as his hand can furnish, and there shall be a hin of oil for the cake."}}, {"v": 8, "ref": "46:8", "o": "וּ/בְ/ב֖וֹא הַ/נָּשִׂ֑יא דֶּ֣רֶךְ אוּלָ֤ם הַ/שַּׁ֨עַר֙ יָב֔וֹא וּ/בְ/דַרְכּ֖/וֹ יֵצֵֽא", "en": {"kjv": "And when the prince shall enter, he shall go in by the way of the porch of that gate, and he shall go forth by the way thereof.", "web": "When the prince shall enter, he shall go in by the way of the porch of the gate, and he shall go out by its way.", "bsb": "When the prince enters, he shall go in through the portico of the gateway, and he shall go out the same way.", "asv": "And when the prince shall enter, he shall go in by the way of the porch of the gate, and he shall go forth by the way thereof.", "ylt": "`And in the coming in of the prince, the way of the porch of the gate he cometh in, and by its way he goeth out.", "dra": "And when the prince is to go in, let him go in by the way of the porch of the gate, and let him go out the same way.", "bbe": "And when the ruler comes in, he is to go in through the covered way of the doorway, and he is to go out by the same way.", "geneva": "And when the prince shall enter, hee shall goe in by the way of the porche of that gate, and hee shall go foorth by the way thereof.", "wycliffe": "And whanne the prince schal entre, entre he bi the weie of the porche of the yate, and go he out bi the same weie.", "rotherham": "And when the prince shall enter, by way of the porch of the gate, shall he go in, and by way thereof, shall he go out.", "darby": "And when the prince cometh in, he shall come in by the way of the porch of the gate, and he shall go out by the way thereof.", "twenty": "", "jps": "And when the prince shall enter, he shall go in by the way of the porch of the gate, and he shall go forth by the way thereof.", "acv": "And when the ruler shall enter, he shall go in by the way of the porch of the gate, and he shall go forth by the way of it.", "anderson": "", "haweis": "", "noyes": "And when the prince shall enter, he shall go in by the way of the porch of that gate, and he shall go forth by the way thereof.", "webster": "And when the prince shall enter, he shall go in by the way of the porch of [that] gate, and he shall go forth by the way of it.", "vulgate": "cumque ingressurus est princeps per viam vestibuli portae ingrediatur et per eandem viam exeat;", "brenton": "And when the prince goes in, he shall go in by the way of the porch of the gate, and he shall go forth by the way of the gate."}}, {"v": 9, "ref": "46:9", "o": "וּ/בְ/ב֨וֹא עַם הָ/אָ֜רֶץ לִ/פְנֵ֣י יְהוָה֮ בַּ/מּֽוֹעֲדִים֒ הַ/בָּ֡א דֶּרֶךְ שַׁ֨עַר צָפ֜וֹן לְ/הִֽשְׁתַּחֲוֺ֗ת יֵצֵא֙ דֶּרֶךְ שַׁ֣עַר נֶ֔גֶב וְ/הַ/בָּא֙ דֶּרֶךְ שַׁ֣עַר נֶ֔גֶב יֵצֵ֖א דֶּרֶךְ שַׁ֣עַר צָפ֑וֹנָ/ה לֹ֣א יָשׁ֗וּב דֶּ֤רֶךְ הַ/שַּׁ֨עַר֙ אֲשֶׁר בָּ֣א ב֔/וֹ כִּ֥י נִכְח֖/וֹ יצאו יֵצֵֽא", "en": {"kjv": "But when the people of the land shall come before the Lord in the solemn feasts, he that entereth in by the way of the north gate to worship shall go out by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate: he shall not return by the way of the gate whereby he came in, but shall go forth over against it.", "web": "But when the people of the land shall come before Yahweh in the appointed feasts, he who enters by the way of the north gate to worship shall go out by the way of the south gate; and he who enters by the way of the south gate shall go out by the way of the north gate: he shall not return by the way of the gate by which he came in, but shall go out straight before him.", "bsb": "When the people of the land come before the LORD at the appointed feasts, whoever enters by the north gate to worship must go out by the south gate, and whoever enters by the south gate must go out by the north gate. No one is to return through the gate by which he entered, but each must go out by the opposite gate.", "asv": "But when the people of the land shall come before Jehovah in the appointed feasts, he that entereth by the way of the north gate to worship shall go forth by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate: he shall not return by the way of the gate whereby he came in, but shall go forth straight before him.", "ylt": "And in the coming in of the people of the land before Jehovah at appointed times, he who hath come in the way of the north gate to bow himself, goeth out the way of the south gate, and he who hath come in the way of the south gate, goeth out by the way of the north gate: he doth not turn back the way of the gate by which he came in, but over-against it he goeth out.", "dra": "But when the people of the land shall go in before the Lord in the solemn feasts, he that goeth in by the north gate to adore, shall go out by the way of the south gate; and he that goeth in by the way of the south gate, shall go out by the way of the north gate: he shall not return by the way of the gate whereby he came in, but shall go out at that over against it.", "bbe": "But when the people of the land come before the Lord at the fixed feasts, he who comes in by the north doorway to give worship is to go out by the south doorway; and he who comes in by the south doorway is to go out by the north doorway: he is not to come back by the doorway through which he went in, but is to go straight before him.", "geneva": "But when the people of the land shall come before the Lord in the solemne feastes, hee that entreth in by the way of the North gate to worship, shall goe out by the way of the South gate: and he that entreth by the way of the South gate, shall goe foorth by the way of the North gate: hee shall not returne by the way of the gate whereby hee came in, but they shall goe forth ouer against it.", "wycliffe": "And whanne the puple of the lond schal entre in the siyt of the Lord, in solempnytees, which puple entrith bi the yate of the north, for to worschipe, go it out bi the wei of the south yate. Certis the puple that entrith bi the weie of the south yate, go out bi the weie of the north yate. It schal not turne ayen bi the weie of the yate, bi which it entride, but euene ayens that weie it schal go out.", "rotherham": "But when the people of the land shall enter before Yahweh on the appointed feasts, he that entereth by way of the north gate to bow down shall go forth by way of the south gate, and he that entereth by way of the south gate shall go forth by way of the north gate,—he shall not return by way of the gate by which he entered, but straight-forward, shall he go forth.", "darby": "And when the people of the land come in before Jehovah in the set feasts, he that cometh in by the way of the north gate to worship shall go out by the way of the south gate; and he that cometh in by the way of the south gate shall go out by the way of the north gate: he shall not return by the way of the gate by which he came in, but shall go out straight before him.", "twenty": "", "jps": "But when the people of the land shall come before HaShem in the appointed seasons, he that entereth by the way of the north gate to worship shall go forth by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate; he shall not return by the way of the gate whereby he came in, but shall go forth straight before him.", "acv": "But when the people of the land shall come before Jehovah in the appointed feasts, he who enters by the way of the north gate to worship shall go forth by the way of the south gate, and he who enters by the way of the south gate shall go forth by the way of the north gate. He shall not return by the way of the gate whereby he came in, but shall go forth straight before him.", "anderson": "", "haweis": "", "noyes": "But when the people of the land come before Jehovah in the solemn feasts, he that entereth by the way of the north gate to worship shall go out by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate; he shall not return by the way of the gate by which he entered, but shall go forth over against it.", "webster": "But when the people of the land shall come before the LORD in the solemn feasts, he that entereth in by the way of the north gate to worship shall go out by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate: he shall not return by the way of the gate by which he came in, but shall go forth over against it.", "vulgate": "et cum intrabit populus terrae in conspectu Domini in sollemnitatibus qui ingreditur per portam aquilonis ut adoret egrediatur per viam portae meridianae porro qui ingreditur per viam portae meridianae egrediatur per viam portae aquilonis non revertetur per viam portae per quam ingressus est sed e regione illius egredietur;", "brenton": "And whenever the people of the land shall go in before the Lord at the feasts, he that goes in by the way of the north gate to worship shall go forth by the way of the south gate; and he that goes in by the way of the south gate shall go forth by the way of the north gate: he shall not return by the gate by which he entered, but he shall go forth opposite it."}}, {"v": 10, "ref": "46:10", "o": "וְֽ/הַ/נָּשִׂ֑יא בְּ/תוֹכָ֤/ם בְּ/בוֹאָ/ם֙ יָב֔וֹא וּ/בְ/צֵאתָ֖/ם יֵצֵֽאוּ", "en": {"kjv": "And the prince in the midst of them, when they go in, shall go in; and when they go forth, shall go forth.", "web": "The prince, when they go in, shall go in with of them; and when they go out, he shall go out.", "bsb": "When the people enter, the prince shall go in with them, and when they leave, he shall leave.", "asv": "And the prince, when they go in, shall go in in the midst of them; and when they go forth, they shall go forth together.", "ylt": "And the prince in their midst in their coming in cometh in, and in their going out he goeth out.", "dra": "And the prince in the midst of them, shall go in when they go in, and go out when they go out.", "bbe": "And the ruler, when they come in, is to come among them, and is to go out when they go out.", "geneva": "And the prince shall be in the middes of them: hee shall go in when they goe in, and when they goe forth, they shall goe forth together.", "wycliffe": "Forsothe the prince schal be in the myddis of hem; he schal entre with hem that entren, and he schal go out with hem that goen out.", "rotherham": "But as for the prince in their midst when they enter, shall he enter, and when they go forth, shall he go forth,", "darby": "And the prince shall come in in the midst of them, when they come in; and when they go out, they shall go out [together].", "twenty": "", "jps": "And the prince, when they go in, shall go in in the midst of them; and when they go forth, they shall go forth together.", "acv": "And the ruler, when they go in, shall go in in the midst of them, and when they go forth, they shall go forth together.", "anderson": "", "haweis": "", "noyes": "And the prince shall go in in the midst of them when they go in, and when they go forth shall he go forth.", "webster": "And the prince in the midst of them, when they go in, shall go in; and when they go forth, shall go forth.", "vulgate": "princeps autem in medio eorum cum ingredientibus ingredietur et cum egredientibus egredietur;", "brenton": "And the prince shall enter with them in the midst of them when they go in; and when they go forth, he shall go forth."}}, {"v": 11, "ref": "46:11", "o": "וּ/בַ/חַגִּ֣ים וּ/בַ/מּוֹעֲדִ֗ים תִּהְיֶ֤ה הַ/מִּנְחָה֙ אֵיפָ֤ה לַ/פָּר֙ וְ/אֵיפָ֣ה לָ/אַ֔יִל וְ/לַ/כְּבָשִׂ֖ים מַתַּ֣ת יָד֑/וֹ וְ/שֶׁ֖מֶן הִ֥ין לָ/אֵיפָֽה", "en": {"kjv": "And in the feasts and in the solemnities the meat offering shall be an ephah to a bullock, and an ephah to a ram, and to the lambs as he is able to give, and an hin of oil to an ephah.", "web": "In the feasts and in the solemnities the meal offering shall be an ephah for a bull, and an ephah for a ram, and for the lambs as he is able to give, and a hin of oil to an ephah.", "bsb": "At the festivals and appointed feasts, the grain offering shall be an ephah with a bull, an ephah with a ram, and as much as one is able to give with the lambs, along with a hin of oil per ephah.", "asv": "And in the feasts and in the solemnities the meal-offering shall be an ephah for a bullock, and an ephah for a ram, and for the lambs as he is able to give, and a hin of oil to an ephah.", "ylt": "`And in feasts, and in appointed times, the present is an ephah for a bullock, and an ephah for a ram, and for lambs the gift of his hand, and of oil a hin for an ephah.", "dra": "And in the fairs, and in the solemnities there shall be the sacrifice of an ephi to a calf, and an ephi to a ram: and to the lambs, the sacrifice shall be as his hand shall find: and a hin of oil to every ephi.", "bbe": "At the feasts and the fixed meetings the meal offerings are to be an ephah for an ox, and an ephah for a male sheep, and for the lambs whatever he is able to give, and a hin of oil to an ephah.", "geneva": "And in the feastes, and in the solemnities the meat offring shalbe an Ephah to a bullocke, and an Ephah to a ram, and to the lambes, the gift of his hand, and an Hin of oyle to an Ephah.", "wycliffe": "And in feiris and in solempnytees, the sacrifice of ephi schal be bi a calf, and ephi bi a wether; in lambren schal be sacrifice as his hond fyndith, and of oile the mesure hyn, bi ech ephi.", "rotherham": "And in the festivals and in the appointed feasts, the meal-offering! shall be an ephah to a bullock, and an ephah to a ram, but to the he-lambs, as one is able to give,—and of oil a hin to an ephah.", "darby": "And on the feast-days, and in the solemnities, the oblation shall be an ephah for a bullock and an ephah for a ram, and for the lambs as he is able to give; and oil, a hin for an ephah.", "twenty": "", "jps": "And in the feasts and in the appointed seasons the meal-offering shall be an ephah for a bullock, and an ephah for a ram, and for the lambs as he is able to give, and a hin of oil to an ephah.", "acv": "And in the feasts and in the solemnities the meal offering shall be an ephah for a bullock, and an ephah for a ram, and for the lambs as he is able to give, and a hin of oil to an ephah.", "anderson": "", "haweis": "", "noyes": "And in the feasts and in the solemn assemblies the flour-offering shall be an ephah for a bullock, and an ephah for a ram, and for the lambs what he is disposed to give; and a hin of oil to an ephah.", "webster": "And in the feasts and in the solemnities the meat-offering shall be an ephah to a bullock, and an ephah to a ram, and to the lambs as he is able to give, and a hin of oil to an ephah.", "vulgate": "et in nundinis et in sollemnitatibus erit sacrificium oephi per vitulum et oephi per arietem agnis autem erit sacrificium sicut invenerit manus eius et olei hin per singula oephi;", "brenton": "And in the feasts and in the general assemblies the freewill oblation shall be a meat-offering for the calf, and a meat-offering for the ram, and for the lambs, as his hand can furnish, and a hin of oil for the meat-offering."}}, {"v": 12, "ref": "46:12", "o": "וְ/כִֽי יַעֲשֶׂה֩ הַ/נָּשִׂ֨יא נְדָבָ֜ה עוֹלָ֣ה אֽוֹ שְׁלָמִים֮ נְדָבָ֣ה לַֽ/יהוָה֒ וּ/פָ֣תַֽח ל֗/וֹ אֶת הַ/שַּׁ֨עַר֙ הַ/פֹּנֶ֣ה קָדִ֔ים וְ/עָשָׂ֤ה אֶת עֹֽלָת/וֹ֙ וְ/אֶת שְׁלָמָ֔י/ו כַּ/אֲשֶׁ֥ר יַעֲשֶׂ֖ה בְּ/י֣וֹם הַ/שַּׁבָּ֑ת וְ/יָצָ֛א וְ/סָגַ֥ר אֶת הַ/שַּׁ֖עַר אַחֲרֵ֥י צֵאתֽ/וֹ", "en": {"kjv": "Now when the prince shall prepare a voluntary burnt offering or peace offerings voluntarily unto the Lord, one shall then open him the gate that looketh toward the east, and he shall prepare his burnt offering and his peace offerings, as he did on the sabbath day: then he shall go forth; and after his going forth one shall shut the gate.", "web": "When the prince shall prepare a freewill offering, a burnt offering or peace offerings as a freewill offering to Yahweh, one shall open for him the gate that looks toward the east; and he shall prepare his burnt offering and his peace offerings, as he does on the Sabbath day: then he shall go out; and after his going out one shall shut the gate.", "bsb": "When the prince makes a freewill offering to the LORD, whether a burnt offering or a peace offering, the gate facing east must be opened for him. He is to offer his burnt offering or peace offering just as he does on the Sabbath day. Then he shall go out, and the gate must be closed after he goes out.", "asv": "And when the prince shall prepare a freewill-offering, a burnt-offering or peace-offerings as a freewill-offering unto Jehovah, one shall open for him the gate that looketh toward the east; and he shall prepare his burnt-offering and his peace-offerings, as he doth on the sabbath day: then he shall go forth; and after his going forth one shall shut the gate.", "ylt": "And when the prince maketh a free-will burnt-offering, or free-will peace-offerings, to Jehovah, then he hath opened for himself the gate that is looking eastward, and he hath made his burnt-offering and his peace-offerings as he doth in the day of rest, and he hath gone out, and he hath shut the gate after his going out.", "dra": "But when the prince shall offer a voluntary holocaust, or voluntary peace offering to the Lord: the gate that looketh towards the east shall be opened to him, and he shall offer his holocaust, and his peace offerings, as it is wont to be done on the sabbath day: and he shall go out, and the gate shall be shut after he is gone forth.", "bbe": "And when the ruler makes a free offering, a burned offering or a peace-offering freely given to the Lord, the doorway looking to the east is to be made open for him, and he is to make his burned offering and his peace-offerings as he does on the Sabbath day: and he will go out; and the door will be shut after he has gone out.", "geneva": "Nowe when the prince shall make a free burnt offring or peace offrings freely vnto the Lord, one shall then open him the gate, that turneth towarde the East, and hee shall make his burnt offring and his peace offrings, as he did on the Sabbath day: after, hee shall goe foorth, and when he is gone forth, one shall shut the gate.", "wycliffe": "Forsothe whanne the prince makith a wilful brent sacrifice, ether wilful pesible sacrifice to the Lord, the yate that biholdith to the eest, schal be openyd to hym; and he schal make his brent sacrifice, and hise pesible sacrifices, as it is wont to be doon in the dai of sabat; and he schal go out, and the yate schal be closid after that he yede out.", "rotherham": "And, when the prince would offer as a freewill offering an ascending-sacrifice or peace-offerings as a free-will offering to Yahweh, then shall be opened to him the gate that looketh to the east, and he shall offer his ascending-sacrifice and his peace-offerings just as he would offer on the sabbath day,- and, when he shall go forth, then shall one shut the gate after he hath gone forth.", "darby": "And when the prince shall offer a voluntary burnt-offering or voluntary peace-offerings unto Jehovah, the gate that looketh toward the east shall be opened for him and he shall offer his burnt-offering and his peace-offerings as he did on the sabbath-day, and he shall go out again, and the gate shall be shut after he hath gone out.", "twenty": "", "jps": "And when the prince shall prepare a freewill-offering, a burnt-offering or peace-offerings as a freewill-offering unto HaShem, one shall open for him the gate that looketh toward the east, and he shall prepare his burnt-offering and his peace-offerings, as he doth on the sabbath day; then he shall go forth; and after his going forth one shall shut the gate.", "acv": "And when the ruler shall prepare a freewill offering, a burnt offering or peace offerings as a freewill offering to Jehovah, a man shall open for him the gate that looks toward the east. And he shall prepare his burnt offering and his peace offerings, as he does on the sabbath day. Then he shall go forth, and after his going forth a man shall shut the gate.", "anderson": "", "haweis": "", "noyes": "And when the prince shall present a free-will burnt-offering or a free-will thank-offering to Jehovah, the gate that looketh toward the east shall be opened for him, and he shall present his burnt-offering, or his thank-offering, as he was wont to do on the sabbath-day; then he shall go forth, and the gate shall be shut after he hath gone forth.", "webster": "Now when the prince shall prepare a voluntary burnt-offering or peace-offerings voluntarily to the LORD, [one] shall then open to him the gate that looketh towards the east, and he shall prepare his burnt-offering and his peace-offerings, as he did on the sabbath-day: then he shall go forth; and after his going forth [one] shall shut the gate.", "vulgate": "cum autem fecerit princeps spontaneum holocaustum aut pacifica voluntaria Domino aperietur ei porta quae respicit ad orientem et faciet holocaustum suum et pacifica sua sicut fieri solet in die sabbati et egredietur claudeturque porta postquam exierit;", "brenton": "And if the prince should prepare as a thanksgiving a whole-burnt-peace-offering to the Lord, and should open for himself the gate looking eastward, and offer his whole-burnt-offering, and his peace-offerings, as he does on the sabbath-day; then shall he go out, and shall shut the doors after he has gone out."}}, {"v": 13, "ref": "46:13", "o": "וְ/כֶ֨בֶשׂ בֶּן שְׁנָת֜/וֹ תָּמִ֗ים תַּעֲשֶׂ֥ה עוֹלָ֛ה לַ/יּ֖וֹם לַֽ/יהֹוָ֑ה בַּ/בֹּ֥קֶר בַּ/בֹּ֖קֶר תַּעֲשֶׂ֥ה אֹתֽ/וֹ", "en": {"kjv": "Thou shalt daily prepare a burnt offering unto the Lord of a lamb of the first year without blemish: thou shalt prepare it every morning.", "web": "You shall prepare a lamb a year old without defect for a burnt offering to Yahweh daily: morning by morning you shall prepare it.", "bsb": "And you shall provide an unblemished year-old lamb as a daily burnt offering to the LORD; you are to offer it every morning.", "asv": "And thou shalt prepare a lamb a year old without blemish for a burnt-offering unto Jehovah daily: morning by morning shalt thou prepare it.", "ylt": "`And a lamb, son of a year, a perfect one, thou dost make a burnt-offering daily to Jehovah; morning by morning thou dost make it.", "dra": "And he shall offer every day for a holocaust to the Lord, a lamb of the same year without blemish: he shall offer it always in the morning.", "bbe": "And you are to give a lamb a year old without any mark on it for a burned offering to the Lord every day: morning by morning you are to give it.", "geneva": "Thou shalt dayly make a burnt offring vnto the Lord of a lambe of one yere without blemish: thou shalt doe it euery morning.", "wycliffe": "And he schal make brent sacrifice ech day to the Lord, a lomb with out wem of the same yeer; euere he schal make it in the morewtid,", "rotherham": "And, a he-lamb of the first year without defect, shalt thou offer as an ascending-sacrifice daily unto Yahweh,— morning by morning shalt thou offer it.", "darby": "And thou shalt daily offer a burnt-offering unto Jehovah, of a yearling-lamb without blemish: thou shalt prepare it morning by morning.", "twenty": "", "jps": "And thou shalt prepare a lamb of the first year without blemish for a burnt-offering unto HaShem daily; morning by morning shalt thou prepare it.", "acv": "And thou shall prepare a lamb a year old without blemish for a burnt offering to Jehovah daily. Thou shall prepare it morning by morning.", "anderson": "", "haweis": "", "noyes": "And thou shalt present for a burnt-offering daily to Jehovah a lamb that is a year old without blemish; every morning shalt thou present it.", "webster": "Thou shalt daily prepare a burnt-offering to the LORD [of] a lamb of the first year without blemish: thou shalt prepare it every morning.", "vulgate": "et agnum eiusdem anni inmaculatum faciet holocaustum cotidie Domino semper mane faciet illud;", "brenton": "And he shall prepare daily as a whole-burnt-offering to the Lord a lamb of a year old without blemish: in the morning shall he prepare it."}}, {"v": 14, "ref": "46:14", "o": "וּ/מִנְחָה֩ תַעֲשֶׂ֨ה עָלָ֜י/ו בַּ/בֹּ֤קֶר בַּ/בֹּ֨קֶר֙ שִׁשִּׁ֣ית הָֽ/אֵיפָ֔ה וְ/שֶׁ֛מֶן שְׁלִישִׁ֥ית הַ/הִ֖ין לָ/רֹ֣ס אֶת הַ/סֹּ֑לֶת מִנְחָה֙ לַֽ/יהוָ֔ה חֻקּ֥וֹת עוֹלָ֖ם תָּמִֽיד", "en": {"kjv": "And thou shalt prepare a meat offering for it every morning, the sixth part of an ephah, and the third part of an hin of oil, to temper with the fine flour; a meat offering continually by a perpetual ordinance unto the Lord.", "web": "You shall prepare a meal offering with it morning by morning, the sixth part of an ephah, and the third part of a hin of oil, to moisten the fine flour; a meal offering to Yahweh continually by a perpetual ordinance.", "bsb": "You are also to provide with it every morning a grain offering of a sixth of an ephah with a third of a hin of oil to moisten the fine flour—a grain offering to the LORD. This is a permanent statute.", "asv": "And thou shalt prepare a meal-offering with it morning by morning, the sixth part of an ephah, and the third part of a hin of oil, to moisten the fine flour; a meal-offering unto Jehovah continually by a perpetual ordinance.", "ylt": "And a present thou dost make for it morning by morning, a sixth part of the ephah, and of oil a third part of the hin, to temper with the fine flour, a present to Jehovah, by a statute age-during--continually;", "dra": "And he shall offer the sacrifice for it morning by morning, the sixth part of an ephi: and the third part of a hin of oil to be mingled with the fine flour: a sacrifice to the Lord by ordinance continual and everlasting.", "bbe": "And you are to give, morning by morning, a meal offering with it, a sixth of an ephah and a third of a hin of oil dropped on the best meal; a meal offering offered to the Lord at all times by an eternal order.", "geneva": "And thou shalt prepare a meate offring for it euery morning, the sixt part of an Ephah, and the thirde part of an Hin of oyle, to mingle with the fine flowre: this meate offring shalbe continually by a perpetuall ordinance vnto the Lord.", "wycliffe": "and he schal make sacrifice on it ful eerli; eerli he schal make the sixte part of ephi, and of oile the thridde part of hyn, that it be meddlid with the floure of wheete; it is a lawful sacrifice, contynuel and euerlastinge, to the Lord.", "rotherham": "And, a meal-offering, shalt thou offer thereupon morning by morning, of the sixth of an ephah and, of oil, the third part of an hin to moisten the fine meal,—a meal-offering to Yahweh, age-abiding statutes continually.", "darby": "And thou shalt prepare an oblation with it every morning, the sixth part of an ephah, and of oil the third part of a hin, to moisten the fine flour: an oblation unto Jehovah continually by a perpetual ordinance.", "twenty": "", "jps": "And thou shalt prepare a meal-offering with it morning by morning, the sixth part of an ephah, and the third part of a hin of oil, to moisten the fine flour: a meal-offering unto HaShem continually by a perpetual ordinance.", "acv": "And thou shall prepare a meal offering with it morning by morning, the sixth part of an ephah, and the third part of a hin of oil, to moisten the fine flour, a meal offering to Jehovah continually by a perpetual ordinance.", "anderson": "", "haweis": "", "noyes": "And thou shalt present with it every morning a flour-offering, the sixth part of an ephah, and the third part of a hin of oil to moisten the fine flour, for a flour-offering to Jehovah, by a perpetual statute continually.", "webster": "And thou shalt prepare a meat-offering for it every morning, the sixth part of an ephah, and the third part of a hin of oil, to temper with the fine flour; a meat-offering continually by a perpetual ordinance to the LORD.", "vulgate": "et sacrificium faciet super eo cata mane mane sextam partem oephi et de oleo tertiam partem hin ut misceatur similae sacrificium Domino legitimum iuge atque perpetuum;", "brenton": "And he shall prepare a freewill-offering for it in the morning, the sixth part of a measure of flour, and a third part of a hin of oil to mix therewith the fine flour, as a freewill-offering to the Lord, a perpetual ordinance."}}, {"v": 15, "ref": "46:15", "o": "ו/עשו יַעֲשׂ֨וּ אֶת הַ/כֶּ֧בֶשׂ וְ/אֶת הַ/מִּנְחָ֛ה וְ/אֶת הַ/שֶּׁ֖מֶן בַּ/בֹּ֣קֶר בַּ/בֹּ֑קֶר עוֹלַ֖ת תָּמִֽיד", "en": {"kjv": "Thus shall they prepare the lamb, and the meat offering, and the oil, every morning for a continual burnt offering.", "web": "Thus shall they prepare the lamb, and the meal offering, and the oil, morning by morning, for a continual burnt offering.", "bsb": "Thus they shall provide the lamb, the grain offering, and the oil every morning as a regular burnt offering.’", "asv": "Thus shall they prepare the lamb, and the meal-offering, and the oil, morning by morning, for a continual burnt-offering.", "ylt": "and prepare ye the lamb, and the present, and the oil, morning by morning, a continual burnt-offering.", "dra": "He shall offer the lamb, and the sacrifice, and the oil morning by morning: an everlasting holocaust.", "bbe": "And they are to give the lamb and the meal offering and the oil, morning by morning, for a burned offering at all times.", "geneva": "Thus shall they prepare the lambe, and the meate offring and the oyle euery morning, for a continual burnt offring.", "wycliffe": "He schal make a lomb, and sacrifice, and oile, ful eerli; he schal make eerli brent sacrifice euerlastynge.", "rotherham": "Thus shall they offer the he-lamb and the meal-offering and the oil morning by morning,—a continual ascending-sacrifice.", "darby": "They shall offer the lamb, and the oblation, and the oil, every morning for a continual burnt-offering.", "twenty": "", "jps": "Thus shall they prepare the lamb, and the meal-offering, and the oil, morning by morning, for a continual burnt-offering.", "acv": "Thus they shall prepare the lamb, and the meal offering, and the oil, morning by morning, for a continual burnt offering.", "anderson": "", "haweis": "", "noyes": "Thus shall they prepare the lamb, and the flour-offering, and the oil, every morning, for a continual burnt-offering.", "webster": "Thus shall they prepare the lamb, and the meat-offering, and the oil, every morning [for] a continual burnt-offering.", "vulgate": "faciet agnum et sacrificium et oleum cata mane mane holocaustum sempiternum;", "brenton": "Ye shall prepare the lamb, and the freewill-offering, and the oil in the morning, for a perpetual whole-burnt-sacrifice."}}, {"v": 16, "ref": "46:16", "o": "כֹּה אָמַ֞ר אֲדֹנָ֣/י יְהֹוִ֗ה כִּֽי יִתֵּ֨ן הַ/נָּשִׂ֤יא מַתָּנָה֙ לְ/אִ֣ישׁ מִ/בָּנָ֔י/ו נַחֲלָת֥/וֹ הִ֖יא לְ/בָנָ֣י/ו תִּֽהְיֶ֑ה אֲחֻזָּתָ֥/ם הִ֖יא בְּ/נַחֲלָֽה", "en": {"kjv": "Thus saith the Lord God; If the prince give a gift unto any of his sons, the inheritance thereof shall be his sons’; it shall be their possession by inheritance.", "web": "Thus says the Lord Yahweh: If the prince give a gift to any of his sons, it is his inheritance, it shall belong to his sons; it is their possession by inheritance.", "bsb": "This is what the Lord GOD says: ‘If the prince gives a gift to any of his sons as an inheritance, it will belong to his descendants. It will become their property by inheritance.", "asv": "Thus saith the Lord Jehovah: If the prince give a gift unto any of his sons, it is his inheritance, it shall belong to his sons; it is their possession by inheritance.", "ylt": "`Thus said the Lord Jehovah: When the prince giveth a gift to any of his sons, his inheritance it is , to his sons it is ; their possession it is by inheritance.", "dra": "Thus saith the Lord God: If the prince give a gift to any of his sons: the inheritance of it shall go to his children, they shall possess it by inheritance.", "bbe": "This is what the Lord has said: If the ruler gives a property to any of his sons, it is his heritage and will be the property of his sons; it is theirs for their heritage.", "geneva": "Thus saith the Lord God, If the prince giue a gift of his inheritance vnto any of his sonnes, it shalbe his sonnes, and it shall bee their possession by inheritance.", "wycliffe": "The Lord God seith these thingis, If the prince yyueth an hous to ony of hise sones, the eritage of hym schal be of hise sones; thei schulen welde it bi eritage.", "rotherham": "Thus saith My Lord Yahweh, When the prince would bestow a gift upon any one of his sons, his own inheritance, shall it be, for his sons, shall it remain,— their possession, shall it be by way of inheritance.", "darby": "Thus saith the Lord Jehovah: If the prince give a gift unto any of his sons, it shall be that one's inheritance, for his sons: it shall be their possession by inheritance.", "twenty": "", "jps": "Thus saith the L-rd GOD: If the prince give a gift unto any of his sons, it is his inheritance, it shall belong to his sons; it is their possession by inheritance.", "acv": "Thus says the lord Jehovah: If the ruler gives a gift to any of his sons, it is his inheritance. It shall belong to his sons. It is their possession by inheritance.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: If the prince give a gift to any of his sons, the inheritance thereof shall belong to his sons; it shall be their possession by inheritance.", "webster": "Thus saith the Lord GOD; If the prince shall give a gift to any of his sons, the inheritance of it shall be to his sons; it [shall be] their possession by inheritance.", "vulgate": "haec dicit Dominus Deus si dederit princeps donum alicui de filiis suis hereditas eius filiorum suorum erit possidebunt ea hereditarie;", "brenton": "Thus saith the Lord God; If the prince shall give a gift to one of his sons out of his inheritance, this shall be to his sons a possession as an inheritance."}}, {"v": 17, "ref": "46:17", "o": "וְ/כִֽי יִתֵּ֨ן מַתָּנָ֜ה מִ/נַּחֲלָת֗/וֹ לְ/אַחַד֙ מֵֽ/עֲבָדָ֔י/ו וְ/הָ֤יְתָה לּ/וֹ֙ עַד שְׁנַ֣ת הַ/דְּר֔וֹר וְ/שָׁבַ֖ת לַ/נָּשִׂ֑יא אַ֚ךְ נַחֲלָת֔/וֹ בָּנָ֖י/ו לָ/הֶ֥ם תִּהְיֶֽה", "en": {"kjv": "But if he give a gift of his inheritance to one of his servants, then it shall be his to the year of liberty; after it shall return to the prince: but his inheritance shall be his sons’ for them.", "web": "But if he give of his inheritance a gift to one of his servants, it shall be his to the year of liberty; then it shall return to the prince; but as for his inheritance, it shall be for his sons.", "bsb": "But if he gives a gift from his inheritance to one of his servants, it will belong to that servant until the year of freedom; then it will revert to the prince. His inheritance belongs only to his sons; it shall be theirs.", "asv": "But if he give of his inheritance a gift to one of his servants, it shall be his to the year of liberty; then it shall return to the prince; but as for his inheritance, it shall be for his sons.", "ylt": "And when he giveth a gift out of his inheritance to one of his servants, then it hath been to him till the year of freedom, and it hath turned back to the prince, only the inheritance of his sons is theirs.", "dra": "But if he give a legacy out of his inheritance to one of his servants, it shall be his until the year of release, and it shall return to the prince: but his inheritance shall go to his sons.", "bbe": "And if he gives a part of his heritage to one of his servants, it will be his till the year of making free, and then it will go back to the ruler; for it is his sons' heritage, and is to be theirs.", "geneva": "But if hee giue a gift of his inheritance to one of his seruantes, then it shall bee his to the yere of libertie: after, it shall returne to ye prince, but his inheritance shall remaine to his sonnes for them.", "wycliffe": "Forsothe if he yyueth a biquest of his eritage to oon of hise seruauntis, it schal be his `til to the yeer of remyssioun, and it schal turne ayen to the prince; forsothe the eritage of hym schal be to hise sones.", "rotherham": "But when he would bestow a gift out of his inheritance on any one of his servants, it shall remain his unto the year of liberation, then shall it return to the prince,—surely it is the inheritance of his sons, theirs, shall it remain.", "darby": "But if he give a gift of his inheritance to one of his servants, it shall be his until the year of liberty; and it shall return to the prince: to his sons alone shall his inheritance remain.", "twenty": "", "jps": "But if he give of his inheritance a gift to one of his servants, it shall be his to the year of liberty; then it shall return to the prince; but as for his inheritance, it shall be for his sons.", "acv": "But if he gives a gift of his inheritance to one of his servants, it shall be his to the year of liberty, then it shall return to the ruler. But as for his inheritance, it shall be for his sons.", "anderson": "", "haweis": "", "noyes": "But if he give a gift of his inheritance to one of his servants, it shall be his to the year of liberty, when it shall return to the prince. But his inheritance given to his sons shall be theirs.", "webster": "But if he shall give a gift of his inheritance to one of his servants, then it shall be his to the year of liberty; afterward it shall return to the prince: but his inheritance shall be to his sons for them.", "vulgate": "si autem dederit legatum de hereditate sua uni servorum suorum erit illius usque ad annum remissionis et revertetur ad principem hereditas autem eius filiis eius erit;", "brenton": "But if he give a gift to one of his servants, then it shall belong to him until the year of release; and then he shall restore it to the prince: but of the inheritance of his sons the possession shall continue to them."}}, {"v": 18, "ref": "46:18", "o": "וְ/לֹא יִקַּ֨ח הַ/נָּשִׂ֜יא מִ/נַּחֲלַ֣ת הָ/עָ֗ם לְ/הֽוֹנֹתָ/ם֙ מֵ/אֲחֻזָּתָ֔/ם מֵ/אֲחֻזָּת֖/וֹ יַנְחִ֣ל אֶת בָּנָ֑י/ו לְמַ֨עַן֙ אֲשֶׁ֣ר לֹֽא יָפֻ֣צוּ עַמִּ֔/י אִ֖ישׁ מֵ/אֲחֻזָּתֽ/וֹ", "en": {"kjv": "Moreover the prince shall not take of the people’s inheritance by oppression, to thrust them out of their possession; but he shall give his sons inheritance out of his own possession: that my people be not scattered every man from his possession.", "web": "Moreover the prince shall not take of the people’s inheritance, to thrust them out of their possession; he shall give inheritance to his sons out of his own possession, that my people not be scattered every man from his possession.", "bsb": "The prince must not take any of the inheritance of the people by evicting them from their property. He is to provide an inheritance for his sons from his own property, so that none of My people will be displaced from his property.’”", "asv": "Moreover the prince shall not take of the people’s inheritance, to thrust them out of their possession; he shall give inheritance to his sons out of his own possession, that my people be not scattered every man from his possession.", "ylt": "And the prince doth not take of the inheritance of the people to oppress them, out of their possession, out of his own possession he doth cause his sons to inherit, so that My people are not scattered each from his possession.'", "dra": "And the prince shall not take of the people's inheritance by violence, nor of their possession: but out of his own possession he shall give an inheritance to his sons: that my people be not dispersed every man from his possession.", "bbe": "And the ruler is not to take the heritage of any of the people, driving them out of their property; he is to give a heritage to his sons out of the property which is his: so that my people may not be sent away from their property.", "geneva": "Moreouer the prince shall not take of the peoples inheritance, nor thrust them out of their possession: but he shall cause his sonnes to inherit of his owne possession, that my people be not scattered euery man from his possession.", "wycliffe": "And the prince schal not take bi violence of the eritage of the puple, and of the possessioun of hem; but of his owne possessioun he schal yyue eritage to hise sones, that my puple be not scaterid, ech man fro his possessioun.", "rotherham": "So then the prince shall not take of the inheritance of the people to oppress them out of their possession, out of his own possession, shall he give an inheritance to his sons,—to the end that my people be not scattered, any one out of his possession.", "darby": "And the prince shall not take of the people's inheritance, to thrust them by oppression out of their possession: he shall give his sons an inheritance out of his own possession: that my people be not scattered every one from his possession.", "twenty": "", "jps": "Moreover the prince shall not take of the people's inheritance, to thrust them wrongfully out of their possession; he shall give inheritance to his sons out of his own possession; that My people be not scattered every man from his possession.'", "acv": "Moreover the ruler shall not take of the people's inheritance, to thrust them out of their possession. He shall give inheritance to his sons out of his own possession, that my people be not scattered each man from his possession.", "anderson": "", "haweis": "", "noyes": "And the prince shall not take of the people’s inheritance, to thrust them out of their possession; but he shall give an inheritance to his sons out of his own possession; that no one of my people may be driven from his possession.", "webster": "Moreover the prince shall not take of the people's inheritance by oppression, to thrust them out of their possession; [but] he shall give his sons' inheritance out of his own possession: that my people be not scattered every man from his possession.", "vulgate": "et non accipiet princeps de hereditate populi per violentiam et de possessione eorum sed de possessione sua hereditatem dabit filiis suis ut non dispergatur populus meus unusquisque a possessione sua;", "brenton": "And the prince shall by no means take of the inheritance of the people, to oppress them: he shall give an inheritance to his sons out of his own possession: that my people be not scattered, every one from his possession."}}, {"v": 19, "ref": "46:19", "o": "וַ/יְבִיאֵ֣/נִי בַ/מָּבוֹא֮ אֲשֶׁ֣ר עַל כֶּ֣תֶף הַ/שַּׁעַר֒ אֶל הַ/לִּשְׁכ֤וֹת הַ/קֹּ֨דֶשׁ֙ אֶל הַ/כֹּ֣הֲנִ֔ים הַ/פֹּנ֖וֹת צָפ֑וֹנָ/ה וְ/הִנֵּה שָׁ֣ם מָק֔וֹם ב/ירכת/ם בַּ/יַּרְכָתַ֖יִם יָֽמָּ/ה", "en": {"kjv": "After he brought me through the entry, which was at the side of the gate, into the holy chambers of the priests, which looked toward the north: and, behold, there was a place on the two sides westward.", "web": "Then he brought me through the entry, which was at the side of the gate, into the holy rooms for the priests, which looked toward the north: and behold, there was a place on the hinder part westward.", "bsb": "Then the man brought me through the entrance at the side of the gate into the holy chambers facing north, which belonged to the priests, and he showed me a place there at the far western end", "asv": "Then he brought me through the entry, which was at the side of the gate, into the holy chambers for the priests, which looked toward the north: and, behold, there was a place on the hinder part westward.", "ylt": "And he bringeth me in through the entrance that is by the side of the gate, unto the holy chambers, unto the priests, that are looking northward, and lo, there is a place in their two sides westward.", "dra": "And he brought me in by the entry that was at the side of the gate, into the chambers of the sanctuary that were for the priests, which looked toward the north. And there was a place bending to the west.", "bbe": "And he took me through by the way in at the side of the doorway into the holy rooms which are the priests', looking to the north: and I saw a place at the side of them to the west.", "geneva": "After, he brought me through the entrie, which was at the side of the gate, into the holy chambers of the Priestes, which stoode towarde the North: and beholde, there was a place at the West side of them.", "wycliffe": "And he ledde me in bi the entryng, that was on the side of the yate, in to the treseries of the seyntuarie to the preestis, whiche treseries bihelden to the north; and there was a place goynge to the west.", "rotherham": "Then he brought me in through the entrance which was by the side of the gate, into the chambers of the holy place for the priests, those facing the north,—and lo! there a place, in the hinder parts westwards.", "darby": "Then he brought me through the passage which was at the side of the gate, into the holy cells which were for the priests, which looked toward the north; and behold, a place was there at the end westward.", "twenty": "", "jps": "Then he brought me through the entry, which was at the side of the gate, into the holy chambers for the priests, which looked toward the north; and, behold, there was a place on the hinder part westward.", "acv": "Then he brought me through the entry, which was at the side of the gate, into the holy chambers for the priests, which looked toward the north. And, behold, there was a place on the rear part westward.", "anderson": "", "haweis": "", "noyes": "Then he brought me through the entry, which was at the side of the gate, into the holy rooms for the priests, which looked toward the north; and behold, there was a place behind toward the west.", "webster": "Afterward he brought me through the entry, which [was] at the side of the gate, into the holy chambers of the priests, which looked towards the north: and behold, there [was] a place on the two sides westward.", "vulgate": "et introduxit me per ingressum qui erat ex latere portae in gazofilacia sanctuarii ad sacerdotes quae respiciebant ad aquilonem et erat ibi locus vergens ad occidentem;", "brenton": "And he brought me into the entrance of the place behind the gate, into the chamber of the sanctuary belonging to the priests, that looks toward the north: and, behold, there was a place set apart."}}, {"v": 20, "ref": "46:20", "o": "וַ/יֹּ֣אמֶר אֵלַ֔/י זֶ֣ה הַ/מָּק֗וֹם אֲשֶׁ֤ר יְבַשְּׁלוּ שָׁם֙ הַ/כֹּ֣הֲנִ֔ים אֶת הָ/אָשָׁ֖ם וְ/אֶת הַ/חַטָּ֑את אֲשֶׁ֤ר יֹאפוּ֙ אֶת הַ/מִּנְחָ֔ה לְ/בִלְתִּ֥י הוֹצִ֛יא אֶל הֶ/חָצֵ֥ר הַ/חִֽיצוֹנָ֖ה לְ/קַדֵּ֥שׁ אֶת הָ/עָֽם", "en": {"kjv": "Then said he unto me, This is the place where the priests shall boil the trespass offering and the sin offering, where they shall bake the meat offering; that they bear them not out into the utter court, to sanctify the people.", "web": "He said to me, This is the place where the priests shall boil the trespass offering and the sin offering, and where they shall bake the meal offering; that they not bring them out into the outer court, to sanctify the people.", "bsb": "and said to me, “This is the place where the priests shall boil the guilt offering and the sin offering, and where they shall bake the grain offering, so that they do not bring them into the outer court and transmit holiness to the people.”", "asv": "And he said unto me, This is the place where the priests shall boil the trespass-offering and the sin-offering, and where they shall bake the meal-offering; that they bring them not forth into the outer court, to sanctify the people.", "ylt": "And he saith unto me, `This is the place where the priests do boil the guilt-offering and the sin-offering, where they bake the present, so as not to bring it out unto the outer court, to sanctify the people.'", "dra": "And he said to me: This is the place where the priests shall boil the sin offering, and the trespass offering: where they shall dress the sacrifice, that they may not bring it out into the outward court, and the people be sanctified.", "bbe": "And he said to me, This is the place where the offering for error and the sin-offering are to be cooked in water by the priests, and where the meal offering is to be cooked in the oven; so that they may not be taken out into the outer square to make the people holy.", "geneva": "Then saide he vnto me, This is the place where the Priestes shall see the the trespasse offering and the sinne offering, where they shall bake the meat offring, that they should not beare them into the vtter court, to sanctifie ye people.", "wycliffe": "And he seide to me, This is the place where prestis schulen sethe, bothe for synne and for trespas; where thei schulen sethe sacrifice, that thei bere not out in to the outermere halle, and the puple be halewid.", "rotherham": "Then said he unto me,— This, is the place where the priests, shall boil, the guilt-bearer and the sin-bearer,—where they shall bake the meal-offering, that one may not carry them forth into the outer court to hallow the people,", "darby": "And he said unto me, This is the place where the priests shall boil the trespass-offering, and the sin-offering, [and] where they shall bake the oblation, that they bring them not out into the outer court, so as to hallow the people.", "twenty": "", "jps": "And he said unto me: 'This is the place where the priests shall boil the guilt-offering and the sin-offering, where they shall bake the meal-offering; that they bring them not forth into the outer court, to sanctify the people.'", "acv": "And he said to me, This is the place where the priests shall boil the trespass offering and the sin offering, and where they shall bake the meal offering, that they not bring them forth into the outer court, to sanctify the people.", "anderson": "", "haweis": "", "noyes": "And he said to me: This is the place where the priests shall boil the trespass-offering, and the sin-offering, and bake the flour-offering; that they may not bear them into the outer court, and so sanctify the people.", "webster": "Then said he to me, This [is] the place where the priests shall boil the trespass-offering and the sin-offering, where they shall bake the meat-offering; that they bear [them] not out into the outer court, to sanctify the people.", "vulgate": "et dixit ad me iste est locus ubi coquent sacerdotes pro delicto et pro peccato ubi coquent sacrificium ut non efferant in atrio exteriori et sanctificetur populus;", "brenton": "And he said to me, This is the place where the priests shall boil the trespass-offerings and the sin-offerings, and there shall they bake the meat-offering always; so as not to carry them out into the outer court, to sanctify the people."}}, {"v": 21, "ref": "46:21", "o": "וַ/יּוֹצִיאֵ֗/נִי אֶל הֶֽ/חָצֵר֙ הַ/חִ֣יצֹנָ֔ה וַ/יַּ֣עֲבִירֵ֔/נִי אֶל אַרְבַּ֖עַת מִקְצוֹעֵ֣י הֶ/חָצֵ֑ר וְ/הִנֵּ֤ה חָצֵר֙ בְּ/מִקְצֹ֣עַ הֶ/חָצֵ֔ר חָצֵ֖ר בְּ/מִקְצֹ֥עַ הֶ/חָצֵֽר", "en": {"kjv": "Then he brought me forth into the utter court, and caused me to pass by the four corners of the court; and, behold, in every corner of the court there was a court.", "web": "Then he brought me out into the outer court, and caused me to pass by the four corners of the court; and behold, in every corner of the court there was a court.", "bsb": "Then he brought me into the outer court and led me around to its four corners, and I saw a separate court in each of its corners.", "asv": "Then he brought me forth into the outer court, and caused me to pass by the four corners of the court; and, behold, in every corner of the court there was a court.", "ylt": "And he bringeth me out unto the outer court, and causeth me to pass over unto the four corners of the court, and lo, a court in a corner of the court, a court in a corner of the corner.", "dra": "And he brought me into the outward court, and he led me about by the four corners of the court: and behold there was a little court in the corner of the court, to every corner of the court there was a little court.", "bbe": "And he took me out into the outer square and made me go by the four angles of the square; and I saw that in every angle of the open square there was a space shut in.", "geneva": "Then he brought me foorth into the vtter court, and caused me to goe by the foure corners of the court: and beholde, in euery corner of the court, there was a court.", "wycliffe": "And he ledde me out in to the outermere halle, and ledde me aboute bi the foure corneris of the halle; and lo! a litil halle was in the corner of the halle, alle litil hallis bi the corneris of the halle;", "rotherham": "So he caused me to go out into the outer court, and then made me pass through into the four corners of the court,—and lo! a court in each corner of the court:", "darby": "And he brought me forth into the outer court, and caused me to pass by the four corners of the court; and behold, in every corner of the court there was a court.", "twenty": "", "jps": "Then he brought me forth into the outer court, and caused me to pass by the four corners of the court; and, behold, in every corner of the court there was a court.", "acv": "Then he brought me forth into the outer court, and caused me to pass by the four corners of the court. And, behold, in every corner of the court there was a court.", "anderson": "", "haweis": "", "noyes": "Then he brought me forth into the outer court, and caused me to pass by the four corners of the court; and behold, there was a court in every corner of the court.", "webster": "Then he brought me forth into the outer court, and caused me to pass by the four corners of the court; and behold, in every corner of the court [there was] a court.", "vulgate": "et eduxit me in atrium exterius et circumduxit me per quattuor angulos atrii et ecce atriolum erat in angulo atrii atriola singula per angulos atrii;", "brenton": "And he brought me into the outer court, and led me round upon the four sides of the court; and, behold, there was a court on each of the sides of the court,"}}, {"v": 22, "ref": "46:22", "o": "בְּ/אַרְבַּ֜עַת מִקְצֹע֤וֹת הֶֽ/חָצֵר֙ חֲצֵר֣וֹת קְטֻר֔וֹת אַרְבָּעִ֣ים אֹ֔רֶךְ וּ/שְׁלֹשִׁ֖ים רֹ֑חַב מִדָּ֣ה אַחַ֔ת לְ/אַרְבַּעְתָּ֖/ם מְׄהֻׄקְׄצָׄעֽׄוֹׄתׄ", "en": {"kjv": "In the four corners of the court there were courts joined of forty cubits long and thirty broad: these four corners were of one measure.", "web": "In the four corners of the court there were courts enclosed, forty cubits long and thirty broad: these four in the corners were of one measure.", "bsb": "In the four corners of the outer court there were enclosed courts, each forty cubits long and thirty cubits wide. Each of the four corner areas had the same dimensions.", "asv": "In the four corners of the court there were courts inclosed, forty cubits long and thirty broad: these four in the corners were of one measure.", "ylt": "In the four corners of the court are perfume courts, forty long, and thirty broad, one measure is to the four corners.", "dra": "In the four corners of the court were little courts disposed, forty cubits long, and thirty broad, all the four were of one measure.", "bbe": "In the four angles there were spaces walled in, forty cubits long and thirty wide; the four were of the same size.", "geneva": "In the foure corners of the court there were courts ioyned of fourty cubits long, and thirty broad: these foure corners were of one measure.", "wycliffe": "in foure corneris of the halle litle hallis weren disposid, of fourti cubitis bi lengthe, and of thretti bi breede;", "rotherham": "in the four corners of the court, were courts covered over, forty long and thirty broad: of one measure, were those four.", "darby": "In the four corners of the court there were enclosed courts, forty [cubits] long and thirty broad: these four corner courts were of one measure.", "twenty": "", "jps": "In the four corners of the court there were courts inclosed, forty cubits long and thirty broad; these four in the corners were of one measure.", "acv": "In the four corners of the court there were courts enclosed, forty long and thirty broad. These four in the corners were of one measure.", "anderson": "", "haweis": "", "noyes": "In the four corners of the court were covered courts forty cubits long, and thirty broad; these four corners were of one measure.", "webster": "In the four corners of the court [there were] courts joined of forty [cubits] long and thirty broad: these four corners [were] of one measure.", "vulgate": "in quattuor angulos atrii atriola disposita quadraginta cubitorum per longum et triginta per latum mensurae unius quattuor erant;", "brenton": "on every side a court, even a court for all the four sides, and each little court belonging to the court was in length forty cubits, and in breadth thirty cubits, there was one measure to the four."}}, {"v": 23, "ref": "46:23", "o": "וְ/ט֨וּר סָבִ֥יב בָּ/הֶ֛ם סָבִ֖יב לְ/אַרְבַּעְתָּ֑/ם וּ/מְבַשְּׁל֣וֹת עָשׂ֔וּי מִ/תַּ֥חַת הַ/טִּיר֖וֹת סָבִֽיב", "en": {"kjv": "And there was a row of building round about in them, round about them four, and it was made with boiling places under the rows round about.", "web": "There was a wall around in them, around the four, and boiling places were made under the walls all around.", "bsb": "Around the inside of each of the four courts was a row of masonry with ovens built at the base of the walls on all sides.", "asv": "And there was a wall round about in them, round about the four, and boiling-places were made under the walls round about.", "ylt": "And a row is round about in them, round about to them four, and made with boilers under the rows round about.", "dra": "And there was a wall round about compassing the four little courts, and there were kitchens built under the rows round about.", "bbe": "And there was a line of wall all round inside them, round all four, and boiling-places were made under it all round about.", "geneva": "And there went a wall about them, euen about those foure, and kitchins were made vnder the walles rounde about.", "wycliffe": "foure weren of o mesure; and a wal bi cumpas yede aboute foure litle hallis; and kychenes weren maad vndur the porchis bi cumpas.", "rotherham": "And there was an enclosure round about in them round about to those four,—and boiling places had been made under the enclosures round about.", "darby": "And there was a row [of building] round about in them, round about those four, and it was made with boiling places under the rows round about.", "twenty": "", "jps": "And there was a row of masonry round about in them, round about the four, and it was made with boiling-places under the rows round about.", "acv": "And there was a wall round about in them, round about the four. And boiling-places were made under the walls round about.", "anderson": "", "haweis": "", "noyes": "And there was in them a wall round about, even round about the four; and boiling-places were made under the walls round about.", "webster": "And [there was] a row [of building] around in them, around them four, and [it was] made with boiling places under the rows around.", "vulgate": "et paries per circuitum ambiens quattuor atriola et culinae fabricatae erant subter porticus per gyrum;", "brenton": "And there were chambers in them round about, round about the four, and cooking-places formed under the chambers round about."}}, {"v": 24, "ref": "46:24", "o": "וַ/יֹּ֖אמֶר אֵלָ֑/י אֵ֚לֶּה בֵּ֣ית הַֽ/מְבַשְּׁלִ֔ים אֲשֶׁ֧ר יְבַשְּׁלוּ שָׁ֛ם מְשָׁרְתֵ֥י הַ/בַּ֖יִת אֶת זֶ֥בַח הָ/עָֽם", "en": {"kjv": "Then said he unto me, These are the places of them that boil, where the ministers of the house shall boil the sacrifice of the people.", "web": "Then he said to me, These are the boiling houses, where the ministers of the house shall boil the sacrifice of the people.", "bsb": "And he said to me, “These are the kitchens where those who minister at the temple will cook the sacrifices offered by the people.”", "asv": "Then said he unto me, These are the boiling-houses, where the ministers of the house shall boil the sacrifice of the people.", "ylt": "And he saith unto me, `These are the houses of those boiling where the ministrants of the house boil the sacrifice of the people.'", "dra": "And he said to me: This is the house of the kitchens wherein the ministers of the house of the Lord shall boil the victims of the people.", "bbe": "And he said to me, These are the boiling-rooms, where the offering of the people is cooked by the servants of the house.", "geneva": "Then said he vnto me, This is the kitchin where the ministers of the house shall seethe the sacrifice of the people.", "wycliffe": "And he seide to me, This is the hous of kichenes, in which the mynystris of the hous of the Lord schulen sethe the sacrifices of the puple.", "rotherham": "And he said unto me,— these, are the places of them who boil where they who wait upon the house shall boil the sacrifice of the people.", "darby": "And he said unto me, These are the boiling-houses, where those who do the service of the house shall boil the sacrifice of the people.", "twenty": "", "jps": "Then said he unto me: 'These are the boiling-places, where the ministers of the house shall boil the sacrifices of the people.'", "acv": "Then said he to me, These are the boiling-houses, where the ministers of the house shall boil the sacrifice of the people.", "anderson": "", "haweis": "", "noyes": "Then said he to me, These are the places of them that boil, where the ministers of the house shall boil the sacrifice of the people.", "webster": "Then said he to me, These [are] the places of them that boil, where the ministers of the house shall boil the sacrifice of the people.", "vulgate": "et dixit ad me haec est domus culinarum in qua coquent ministri domus Domini victimas populi;", "brenton": "And he said to me, These are the cooks' houses, where they that serve the house shall boil the sacrifices of the people."}}]}, {"c": 47, "verses": [{"v": 1, "ref": "47:1", "o": "וַ/יְשִׁבֵ/נִי֮ אֶל פֶּ֣תַח הַ/בַּיִת֒ וְ/הִנֵּה מַ֣יִם יֹצְאִ֗ים מִ/תַּ֨חַת מִפְתַּ֤ן הַ/בַּ֨יִת֙ קָדִ֔ימָ/ה כִּֽי פְנֵ֥י הַ/בַּ֖יִת קָדִ֑ים וְ/הַ/מַּ֣יִם יֹרְדִ֗ים מִ/תַּ֜חַת מִ/כֶּ֤תֶף הַ/בַּ֨יִת֙ הַ/יְמָנִ֔ית מִ/נֶּ֖גֶב לַ/מִּזְבֵּֽחַ", "en": {"kjv": "Afterward he brought me again unto the door of the house; and, behold, waters issued out from under the threshold of the house eastward: for the forefront of the house stood toward the east, and the waters came down from under from the right side of the house, at the south side of the altar.", "web": "He brought me back to the door of the house; and behold, waters issued out from under the threshold of the house eastward; (for the forefront of the house was toward the east;) and the waters came down from under, from the right side of the house, on the south of the altar.", "bsb": "Then the man brought me back to the entrance of the temple, and I saw water flowing from under the threshold of the temple toward the east (for the temple faced east). The water was coming down from under the south side of the temple, south of the altar.", "asv": "And he brought me back unto the door of the house; and, behold, waters issued out from under the threshold of the house eastward (for the forefront of the house was toward the east); and the waters came down from under, from the right side of the house, on the south of the altar.", "ylt": "And he causeth me to turn back unto the opening of the house; and lo, water is coming forth from under the threshold of the house eastward, for the front of the house is eastward, and the water is coming down from beneath, from the right side of the house, from the south of the altar.", "dra": "And he brought me again to the gate of the house, and behold waters issued out from under the threshold of the house toward the east: for the forefront of the house looked toward the east: but the waters came down to the right side of the temple to the south part of the altar.", "bbe": "And he took me back to the door of the house; and I saw that waters were flowing out from under the doorstep of the house on the east, for the house was facing east: and the waters came down from under, from the right side of the house, on the south side of the altar.", "geneva": "Afterward he brought me vnto the doore of the house: and behold, waters yssued out from vnder the threshold of the house Eastward: for the forefront of the house stoode towarde the East, and the waters ran downe from vnder the right side of the house, at the southside of ye altar.", "wycliffe": "And he turnede me to the yate of the hous; and lo! watris yeden out vndur the threisfold of the hous to the eest; for the face of the hous bihelde to the eest; forsothe the watris camen doun in to the riyt side of the temple, to the south part of the auter.", "rotherham": "Then he brought me back unto the entrance of the house, and lo! waters coming forth from under the threshold of the house eastward, because the front of the house, was to the east,—and the waters, were coming down from beneath, from the right side of the house, on the south of the altar.", "darby": "And he brought me back to the door of the house; and behold, waters issued out from under the threshold of the house eastward: for the front of the house was eastward. And the waters came down from under, from the right side of the house, south of the altar.", "twenty": "", "jps": "And he brought me back unto the door of the house; and, behold, waters issued out from under the threshold of the house eastward, for the forefront of the house looked toward the east; and the waters came down from under, from the right side of the house, on the south of the altar.", "acv": "And he brought me back to the door of the house. And, behold, waters issued out from under the threshold of the house eastward, for the forefront of the house was toward the east. And the waters came down from under, from the right side of the house, on the south of the altar.", "anderson": "", "haweis": "", "noyes": "Afterward he brought me again to the door of the house; and behold, waters issued forth from under the threshold of the house eastward; for the fore-front of the house stood toward the east. And the waters flowed down from the side of the house, south of the altar.", "webster": "Afterward he brought me again to the door of the house; and behold, waters issued out from under the threshhold of the house eastward: for the front of the house [stood towards] the east, and the waters came down from under from the right side of the house, at the south [side] of the altar.", "vulgate": "et convertit me ad portam domus et ecce aquae egrediebantur subter limen domus ad orientem facies enim domus respiciebat ad orientem aquae autem descendebant in latus templi dextrum ad meridiem altaris;", "brenton": "And he brought me to the entrance of the house; and, behold, water issued from under the porch eastward, for the front of the house looked eastward; and the water came down from the right side, from the south to the altar."}}, {"v": 2, "ref": "47:2", "o": "וַ/יּוֹצִאֵ/נִי֮ דֶּֽרֶךְ שַׁ֣עַר צָפוֹנָ/ה֒ וַ/יְסִבֵּ֨/נִי֙ דֶּ֣רֶךְ ח֔וּץ אֶל שַׁ֣עַר הַ/ח֔וּץ דֶּ֖רֶךְ הַ/פּוֹנֶ֣ה קָדִ֑ים וְ/הִנֵּה מַ֣יִם מְפַכִּ֔ים מִן הַ/כָּתֵ֖ף הַ/יְמָנִֽית", "en": {"kjv": "Then brought he me out of the way of the gate northward, and led me about the way without unto the utter gate by the way that looketh eastward; and, behold, there ran out waters on the right side.", "web": "Then he brought me out by the way of the gate northward, and led me round by the way outside to the outer gate, by the way of the gate that looks toward the east; and behold, there ran out waters on the right side.", "bsb": "Next he brought me out through the north gate and led me around the outside to the outer gate facing east, and there I saw the water trickling out from the south side.", "asv": "Then he brought me out by the way of the gate northward, and led me round by the way without unto the outer gate, by the way of the gate that looketh toward the east; and, behold, there ran out waters on the right side.", "ylt": "And he causeth me to go out the way of the gate northward, and causeth me to turn round the way without, unto the gate that is without, the way that is looking eastward, and lo, water is coming forth from the right side.", "dra": "And he led me out by the way of the north gate, and he caused me to turn to the way without the outward gate to the way that looked toward the east: and behold there ran out waters on the right side.", "bbe": "And he took me out by the north doorway, and made me go round to the outside of the doorway looking to the east; and I saw waters running slowly out on the south side.", "geneva": "Then brought he me out toward the North gate, and led me about by the way without vnto the vtter gate, by the way that turneth Eastward: and behold, there came forth waters on ye right side", "wycliffe": "And he ledde me out bi the weie of the north yate, and he turnede me to the weie with out the outermere yate, to the weie that biholdith to the eest; and lo! watris flowynge fro the riyt side,", "rotherham": "Then he brought me out by way of the north gate, and took me round by an outer way, unto an outer gate that which looketh eastward—and lo! waters trickling forth out of the right side.", "darby": "And he brought me out by the way of the gate northward, and led me round outside unto the outer gate towards [the gate] that looketh eastward; and behold, waters ran out on the right side.", "twenty": "", "jps": "Then brought he me out by the way of the gate northward, and led me round by the way without unto the outer gate, by the way of the gate that looketh toward the east; and, behold, there trickled forth waters on the right side.", "acv": "Then he brought me out by the way of the gate northward, and led me round by the way outside to the outer gate, by the way of the gate that looks toward the east. And, behold, waters ran out on the right side.", "anderson": "", "haweis": "", "noyes": "Then he brought me out by the way of the gate northward; and he brought me round by the way without to the outer gate, that looked toward the east; and behold, there ran out waters from the right side.", "webster": "Then he brought me out of the way of the gate northward, and led me about the way without to the outer gate by the way that looketh eastward; and behold, there ran out waters on the right side.", "vulgate": "et eduxit me per viam portae aquilonis et convertit me ad viam foras portam exteriorem viam quae respiciebat ad orientem et ecce aquae redundantes a latere dextro;", "brenton": "And he brought me out by the way of the northern gate, and he led me round by the way outside to the gate of the court that looks eastward; and, behold, water came down from the right side,"}}, {"v": 3, "ref": "47:3", "o": "בְּ/צֵאת הָ/אִ֥ישׁ קָדִ֖ים וְ/קָ֣ו בְּ/יָד֑/וֹ וַ/יָּ֤מָד אֶ֨לֶף֙ בָּֽ/אַמָּ֔ה וַ/יַּעֲבִרֵ֥/נִי בַ/מַּ֖יִם מֵ֥י אָפְסָֽיִם", "en": {"kjv": "And when the man that had the line in his hand went forth eastward, he measured a thousand cubits, and he brought me through the waters; the waters were to the ankles.", "web": "When the man went out eastward with the line in his hand, he measured one thousand cubits, and he caused me to pass through the waters, waters that were to the ankles.", "bsb": "As the man went eastward with a measuring line in his hand, he measured off a thousand cubits and led me through ankle-deep water.", "asv": "When the man went forth eastward with the line in his hand, he measured a thousand cubits, and he caused me to pass through the waters, waters that were to the ankles.", "ylt": "In the going out of the man eastward, and a line in his hand, then he measureth a thousand by the cubit, and he causeth me to pass over into water--water to the ankles.", "dra": "And when the man that had the line in his hand went out towards the east, he measured a thousand cubits: and he brought me through the water up to the ankles.", "bbe": "And the man went out to the east with the line in his hand, and after measuring a thousand cubits, he made me go through the waters, which came over my feet.", "geneva": "And when the man that had the line in his hand, went foorth Eastward, he measured a thousand cubites, and he brought me through the waters: the waters were to the ancles.", "wycliffe": "whanne the man that hadde a coord in his hond, yede out to the eest. And he mat a thousynde cubitis, and ledde me ouer thorou the water til to the heelis.", "rotherham": "When the man went forth with a measuring line in his hand, then measured he a thousand, by the cubit, and caused me to pass through the waters—waters reaching to the ankles.", "darby": "When the man went forth eastward, a line was in his hand; and he measured a thousand cubits, and he caused me to pass through the waters: the waters were to the ankles.", "twenty": "", "jps": "When the man went forth eastward with the line in his hand, he measured a thousand cubits, and he caused me to pass through the waters, waters that were to the ankles.", "acv": "When the man went forth eastward with the line in his hand, he measured a thousand cubits, and he caused me to pass through the waters, waters that were to the ankles.", "anderson": "", "haweis": "", "noyes": "And when the man that had the line in his hand went forth eastward, he measured a thousand cubits, and he led me through the waters, and the waters were to the soles of the feet.", "webster": "And when the man that had the line in his hand went forth eastward, he measured a thousand cubits, and he brought me through the waters; the waters [were] to the ankles.", "vulgate": "cum egrederetur vir ad orientem qui habebat funiculum in manu sua et mensus est mille cubitos et transduxit me per aquam usque ad talos;", "brenton": "in the direction in which a man went forth opposite; and there was a measuring line in his hand, and he measured a thousand cubits with the measure;"}}, {"v": 4, "ref": "47:4", "o": "וַ/יָּ֣מָד אֶ֔לֶף וַ/יַּעֲבִרֵ֥/נִי בַ/מַּ֖יִם מַ֣יִם בִּרְכָּ֑יִם וַ/יָּ֣מָד אֶ֔לֶף וַ/יַּעֲבִרֵ֖/נִי מֵ֥י מָתְנָֽיִם", "en": {"kjv": "Again he measured a thousand, and brought me through the waters; the waters were to the knees. Again he measured a thousand, and brought me through; the waters were to the loins.", "web": "Again he measured one thousand, and caused me to pass through the waters, waters that were to the knees. Again he measured one thousand, and caused me to pass through waters that were to the waist.", "bsb": "Then he measured off a thousand cubits and led me through knee-deep water. Again he measured a thousand cubits and led me through waist-deep water.", "asv": "Again he measured a thousand, and caused me to pass through the waters, waters that were to the knees. Again he measured a thousand, and caused me to pass through the waters, waters that were to the loins.", "ylt": "And he measureth a thousand, and causeth me to pass over into water--water to the knees. And he measureth a thousand, and causeth me to pass over--water to the loins.", "dra": "And again he measured a thousand, and he brought me through the water up to the knees.", "bbe": "And again, measuring a thousand cubits, he made me go through the waters which came up to my knees. Again, measuring a thousand, he made me go through the waters up to the middle of my body.", "geneva": "Againe he measured a thousande, and brought me through the waters: the waters were to the knees: againe he measured a thousand, and brought me through: ye waters were to ye loynes.", "wycliffe": "And eft he mat a thousynde, and ledde me ouer thorouy the watir `til to the knees.", "rotherham": "Then measured he a thousand, and caused me to pass through the waters—waters reaching to the knees,—and again measured he a thousand, and caused me to pass through-waters reaching to the loins.", "darby": "And he measured a thousand [cubits], and caused me to pass through the waters: the waters were to the knees. And he measured a thousand and caused me to pass through: the waters were to the loins.", "twenty": "", "jps": "Again he measured a thousand, and caused me to pass through the waters, waters that were to the knees. Again he measured a thousand, and caused me to pass through waters that were to the loins.", "acv": "Again he measured a thousand, and caused me to pass through the waters, waters that were to the knees. Again he measured a thousand, and caused me to pass through the waters, waters that were to the loins.", "anderson": "", "haweis": "", "noyes": "Again he measured a thousand cubits, and led me through the waters, and the waters were to the knees. Again he measured a thousand cubits, and led me through, and the waters were to the loins.", "webster": "Again he measured a thousand, and brought me through the waters; the waters [were] to the knees. Again he measured a thousand, and brought me through; the waters [were] to the loins.", "vulgate": "rursumque mensus est mille et transduxit me per aquam usque ad genua;", "brenton": "and he passed through the water; it was water of a fountain: and again he measured a thousand, and passed through the water; and the water was up to the thighs: and again he measured a thousand; and he passed through water up to the loins."}}, {"v": 5, "ref": "47:5", "o": "וַ/יָּ֣מָד אֶ֔לֶף נַ֕חַל אֲשֶׁ֥ר לֹֽא אוּכַ֖ל לַ/עֲבֹ֑ר כִּֽי גָא֤וּ הַ/מַּ֨יִם֙ מֵ֣י שָׂ֔חוּ נַ֖חַל אֲשֶׁ֥ר לֹֽא יֵעָבֵֽר", "en": {"kjv": "Afterward he measured a thousand; and it was a river that I could not pass over: for the waters were risen, waters to swim in, a river that could not be passed over.", "web": "Afterward he measured one thousand; and it was a river that I could not pass through; for the waters were risen, waters to swim in, a river that could not be passed through.", "bsb": "Once again he measured off a thousand cubits, but now it was a river that I could not cross, because the water had risen and was deep enough for swimming—a river that could not be crossed on foot.", "asv": "Afterward he measured a thousand; and it was a river that I could not pass through; for the waters were risen, waters to swim in, a river that could not be passed through.", "ylt": "And he measureth a thousand--a stream that I am not able to pass over; for risen have the waters--waters to swim in--a stream that is not passed over.", "dra": "And he measured a thousand, and he brought me through the water up to the loins. And he measured a thousand, and it was a torrent, which I could not pass over: for the waters were risen so as to make a deep torrent, which could not be passed over.", "bbe": "Again, after his measuring a thousand, it became a river which it was not possible to go through: for the waters had become deep enough for swimming, a river it was not possible to go through.", "geneva": "Afterward he measured a thousand, and it was a riuer, that I could not passe ouer: for the waters were risen, and the waters did flowe, as a riuer that could not be passed ouer.", "wycliffe": "And eft he mat a thousynde, and ledde me ouer thorouy the watir `til to the reynes. And he mat a thousynde, the stronde which Y myyte not passe; for the depe watris of the stronde hadden wexe greet, that mai not be waad ouer.", "rotherham": "Then measured he a thousand—a river which I could not pass through—for the waters had risen-waters to swim in, a river, that could not be forded.", "darby": "And he measured a thousand: it was a river that I could not pass through, for the waters were risen, waters to swim in, a river that could not be passed through.", "twenty": "", "jps": "Afterward he measured a thousand; and it was a river that I could not pass through; for the waters were risen, waters to swim in, a river that could not be passed through.", "acv": "Afterward he measured a thousand, and it was a river that I could not pass through, for the waters were risen, waters to swim in, a river that could not be passed through.", "anderson": "", "haweis": "", "noyes": "Again he measured a thousand cubits, and it was a river, which I could not pass through; for the waters were high, waters to swim in, a river which could not be passed through.", "webster": "Afterward he measured a thousand; [and it was] a river that I could not pass over: for the waters had risen, waters to swim in, a river that could not be passed over.", "vulgate": "et mensus est mille et transduxit me per aquam usque ad renes et mensus est mille torrentem quem non potui pertransire quoniam intumuerant aquae profundae torrentis qui non potest transvadari;", "brenton": "and again he measured a thousand; and he could not pass through: for the water rose as of a torrent which men cannot pass over."}}, {"v": 6, "ref": "47:6", "o": "וַ/יֹּ֥אמֶר אֵלַ֖/י הֲ/רָאִ֣יתָ בֶן אָדָ֑ם וַ/יּוֹלִכֵ֥/נִי וַ/יְשִׁבֵ֖/נִי שְׂפַ֥ת הַ/נָּֽחַל", "en": {"kjv": "And he said unto me, Son of man, hast thou seen this? Then he brought me, and caused me to return to the brink of the river.", "web": "He said to me, Son of man, have you seen? Then he brought me, and caused me to return to the bank of the river.", "bsb": "“Son of man, do you see this?” he asked. Then he led me back to the bank of the river.", "asv": "And he said unto me, Son of man, hast thou seen this? Then he brought me, and caused me to return to the bank of the river.", "ylt": "And he saith unto me, `Hast thou seen, son of man?' and he leadeth me, and bringeth me back unto the edge of the stream.", "dra": "And he said to me: Surely thou hast seen, O son of man. And he brought me out, and he caused me to turn to the bank of the torrent.", "bbe": "And he said to me, Son of man, have you seen this? Then he took me to the river's edge.", "geneva": "And he said vnto me, Sonne of man, hast thou seene this? Then he brought me, and caused me to returne to the brinke of the riuer.", "wycliffe": "And he seide to me, Certis, sone of man, thou hast seyn. And he seide to me; and he turnede me to the ryuere of the stronde.", "rotherham": "Then said he unto me Hast thou seen son of man? Then he took me along and caused me to return to the bank of the river.", "darby": "And he said unto me, Son of man, hast thou seen [this]? And he led me, and brought me back to the bank of the river.", "twenty": "", "jps": "And he said unto me: 'Hast thou seen this, O son of man?' Then he led me, and caused me to return to the bank of the river.", "acv": "And he said to me, Son of man, have thou seen this? Then he brought me, and caused me to return to the bank of the river.", "anderson": "", "haweis": "", "noyes": "And he said to me, Hast thou seen this, son of man? Then he brought me back to the brink of the river.", "webster": "And he said to me, Son of man, hast thou seen [this]? Then he brought me, and caused me to return to the brink of the river.", "vulgate": "et dixit ad me certe vidisti fili hominis et duxit me et convertit ad ripam torrentis;", "brenton": "And he said to me, Hast thou seen this, son of man? Then he brought me, and led me back to the brink of the river"}}, {"v": 7, "ref": "47:7", "o": "בְּ/שׁוּבֵ֕/נִי וְ/הִנֵּה֙ אֶל שְׂפַ֣ת הַ/נַּ֔חַל עֵ֖ץ רַ֣ב מְאֹ֑ד מִ/זֶּ֖ה וּ/מִ/זֶּֽה", "en": {"kjv": "Now when I had returned, behold, at the bank of the river were very many trees on the one side and on the other.", "web": "Now when I had returned, behold, on the bank of the river were very many trees on the one side and on the other.", "bsb": "When I arrived, I saw a great number of trees along both banks of the river.", "asv": "Now when I had returned, behold, upon the bank of the river were very many trees on the one side and on the other.", "ylt": "In my turning back, then, lo, at the edge of the stream are very many trees, on this side and on that side.", "dra": "And when I had turned myself, behold on the bank of the torrent were very many trees on both sides.", "bbe": "And he took me back, and I saw at the edge of the river a very great number of trees on this side and on that.", "geneva": "Nowe when I returned, beholde, at the brinke of the riuer were very many trees on the one side, and on the other.", "wycliffe": "And whanne Y hadde turned me, lo! in the ryuer of the stronde ful many trees on euer either side.", "rotherham": "When I returned, then lo! by the bank of the river, trees very many,—on this side and on that side.", "darby": "When I returned, behold, on the bank of the river were very many trees on the one side and on the other.", "twenty": "", "jps": "Now when I had been brought back, behold, upon the bank of the river were very many trees on the one side and on the other.", "acv": "Now when I had returned, behold, upon the bank of the river were very many trees on the one side and on the other.", "anderson": "", "haweis": "", "noyes": "Now when I had returned, behold, at the brink of the river were very many trees, on the one side and on the other.", "webster": "Now when I had returned, behold, at the bank of the river [were] very many trees on the one side and on the other.", "vulgate": "cumque me convertissem ecce in ripa torrentis ligna multa nimis ex utraque parte;", "brenton": "as I returned; and, behold, on the brink of the river there were very many trees on this side and on that side."}}, {"v": 8, "ref": "47:8", "o": "וַ/יֹּ֣אמֶר אֵלַ֗/י הַ/מַּ֤יִם הָ/אֵ֨לֶּה֙ יוֹצְאִ֗ים אֶל הַ/גְּלִילָה֙ הַ/קַּדְמוֹנָ֔ה וְ/יָרְד֖וּ עַל הָֽ/עֲרָבָ֑ה וּ/בָ֣אוּ הַ/יָּ֔מָּ/ה אֶל הַ/יָּ֥מָּ/ה הַ/מּֽוּצָאִ֖ים ו/נרפאו וְ/נִרְפּ֥וּ הַ/מָּֽיִם", "en": {"kjv": "Then said he unto me, These waters issue out toward the east country, and go down into the desert, and go into the sea: which being brought forth into the sea, the waters shall be healed.", "web": "Then he said to me, These waters flow out toward the eastern region, and will go down into the Arabah; and they will go toward the sea; and flow into the sea which will be made to flow out; and the waters will be healed.", "bsb": "And he said to me, “This water flows out to the eastern region and goes down into the Arabah. When it empties into the Sea, the water there becomes fresh.", "asv": "Then said he unto me, These waters issue forth toward the eastern region, and shall go down into the Arabah; and they shall go toward the sea; into the sea shall the waters go which were made to issue forth; and the waters shall be healed.", "ylt": "And he saith unto me, `These waters are going forth unto the east circuit, and have gone down unto the desert, and have entered the sea; unto the sea they are brought forth, and the waters have been healed.", "dra": "And he said to me: These waters that issue forth toward the hillocks of sand to the east, and go down to the plains of the desert, shall go into the sea, and shall go out, and the waters shall be healed.", "bbe": "And he said to me, These waters are flowing out to the east part of the land and down into the Arabah; and they will go to the sea, and the waters will be made sweet.", "geneva": "Then saide he vnto me, These waters issue out towarde the East countrey, and runne downe into the plaine, and shall goe into one sea: they shall runne into another sea, and the waters shalbe wholesome.", "wycliffe": "And he seide to me, These watris that goon out to the heepis of soond of the eest, and goen doun to pleyn places of desert, schulen entre in to the see, and schulen go out; and the watris schulen be heelid.", "rotherham": "And he said unto me, These waters, are going forth unto the region toward the east and shall go down unto the waste plain, and shall enter the sea, unto the sea being led forth, then shall the waters be healed;", "darby": "And he said unto me, These waters issue out toward the east district, and go down into the plain, and go into the sea; when they are brought forth into the sea, the waters [thereof] shall be healed.", "twenty": "", "jps": "Then said he unto me: 'These waters issue forth toward the eastern region, and shall go down into the Arabah; and when they shall enter into the sea, into the sea of the putrid waters, the waters shall be healed.", "acv": "Then he said to me, These waters issue forth toward the eastern region, and shall go down into the Arabah. And they shall go toward the sea, into the sea which were made to issue forth, and the waters shall be healed.", "anderson": "", "haweis": "", "noyes": "Then said he to me, These waters issue forth toward the east region, and run down into the desert, and go into the sea; they go forth into the sea, and the waters shall be healed.", "webster": "Then said he to me, These waters issue out towards the east country, and go down into the desert, and go into the sea: [which being] brought forth into the sea, the waters shall be healed.", "vulgate": "et ait ad me aquae istae quae egrediuntur ad tumulos sabuli orientalis et descendunt ad plana deserti intrabunt mare et exibunt et sanabuntur aquae;", "brenton": "And he said to me, This is the water that goes forth to Galilee that lies eastward, and it is gone down to Arabia, and has reached as far as to the sea to the outlet of the water: and it shall heal the waters."}}, {"v": 9, "ref": "47:9", "o": "וְ/הָיָ֣ה כָל נֶ֣פֶשׁ חַיָּ֣ה אֲֽשֶׁר יִשְׁרֹ֡ץ אֶ֣ל כָּל אֲשֶׁר֩ יָב֨וֹא שָׁ֤ם נַחֲלַ֨יִם֙ יִֽחְיֶ֔ה וְ/הָיָ֥ה הַ/דָּגָ֖ה רַבָּ֣ה מְאֹ֑ד כִּי֩ בָ֨אוּ שָׁ֜מָּ/ה הַ/מַּ֣יִם הָ/אֵ֗לֶּה וְ/יֵרָֽפְאוּ֙ וָ/חָ֔י כֹּ֛ל אֲשֶׁר יָ֥בוֹא שָׁ֖מָּ/ה הַ/נָּֽחַל", "en": {"kjv": "And it shall come to pass, that every thing that liveth, which moveth, whithersoever the rivers shall come, shall live: and there shall be a very great multitude of fish, because these waters shall come thither: for they shall be healed; and every thing shall live whither the river cometh.", "web": "It shall happen, that every living creature which swarms, in every place where the rivers come, shall live; and there shall be a very great multitude of fish; for these waters have come there, and the waters of the sea shall be healed, and everything shall live wherever the river comes.", "bsb": "Wherever the river flows, there will be swarms of living creatures and a great number of fish, because it flows there and makes the waters fresh; so wherever the river flows, everything will flourish.", "asv": "And it shall come to pass, that every living creature which swarmeth, in every place whither the rivers come, shall live; and there shall be a very great multitude of fish; for these waters are come thither, and the waters of the sea shall be healed, and everything shall live whithersoever the river cometh.", "ylt": "And it hath come to pass, every living creature that teemeth, whithersoever the streams come, doth live: and there hath been great abundance of fish, for these waters have come thither, and they are healed; and every thing whither the stream cometh hath lived.", "dra": "And every living creature that creepeth whithersoever the torrent shall come, shall live: and there shall be fishes in abundance after these waters shall come thither, and they shall be healed, and all things shall live to which the torrent shall come.", "bbe": "And it will come about that every living and moving thing, wherever their streams come, will have life; and there will be very much fish because these waters have come there and have been made sweet: and everything wherever the river comes will have life.", "geneva": "And euery thing that liueth, which moueth, wheresoeuer the riuers shall come, shall liue, and there shalbe a very great multitude of fish, because these waters shall come thither: for they shall be wholesome, and euery thing shall liue whither the riuer commeth.", "wycliffe": "And ech lyuynge beeste that creepith, schal lyue, whidur euere the stronde schal come; and fischis many ynow schulen be, aftir that these watris comen thidur, and schulen be heelid, and schulen lyue; alle thingis to whiche the stronde schal come, schulen lyue.", "rotherham": "And it shall come to pass that every living soul that swarmeth whithersoever the rivers shall come, shall live, and the fish shall become a very great multitude; for these waters have come thither, that they may be healed so shall everything live whithersoever the river cometh.", "darby": "And it shall come to pass that every living thing which moveth, whithersoever the double river shall come, shall live. And there shall be a very great multitude of fish; for these waters shall come thither, and [the waters of the sea] shall be healed; and everything shall live whither the river cometh.", "twenty": "", "jps": "And it shall come to pass, that every living creature wherewith it swarmeth, whithersoever the rivers shall come, shall live; and there shall be a very great multitude of fish; for these waters are come thither, that all things be healed and may live whithersoever the river cometh.", "acv": "And it shall come to pass, that every living creature which swarms, in every place where the rivers come, shall live. And there shall be a very great multitude of fish (for these waters have come there) and shall be healed. And everything shall live wherever the river comes.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass, that every living thing that moveth, whithersoever the river shall come, shall live, and there shall be very many fish there; for when these waters shall come thither, [the waters of the sea] shall be healed, and everything shall live whither the river cometh.", "webster": "And it shall come to pass, [that] every thing that liveth, which moveth, whithersoever the rivers shall come, shall live: and there shall be a very great multitude of fish, because these waters shall come thither: for they shall be healed; and every thing shall live whither the river cometh.", "vulgate": "et omnis anima vivens quae serpit quocumque venerit torrens vivet et erunt pisces multi satis postquam venerint illuc aquae istae et sanabuntur et vivent omnia ad quae venerit torrens;", "brenton": "And it shall come to pass, that every animal of living and moving creatures, all on which the river shall come, shall live: and there shall be there very many fish; for this water shall go thither, and it shall heal them, and they shall live: everything on which the river shall come shall live."}}, {"v": 10, "ref": "47:10", "o": "וְ/הָיָה֩ יעמדו עָמְד֨וּ עָלָ֜י/ו דַּוָּגִ֗ים מֵ/עֵ֥ין גֶּ֨דִי֙ וְ/עַד עֵ֣ין עֶגְלַ֔יִם מִשְׁט֥וֹחַ לַֽ/חֲרָמִ֖ים יִהְי֑וּ לְ/מִינָ/ה֙ תִּהְיֶ֣ה דְגָתָ֔/ם כִּ/דְגַ֛ת הַ/יָּ֥ם הַ/גָּד֖וֹל רַבָּ֥ה מְאֹֽד", "en": {"kjv": "And it shall come to pass, that the fishers shall stand upon it from En–gedi even unto En–eglaim; they shall be a place to spread forth nets; their fish shall be according to their kinds, as the fish of the great sea, exceeding many.", "web": "It shall happen, that fishermen shall stand by it: from En Gedi even to En Eglaim shall be a place for the spreading of nets; their fish shall be after their kinds, as the fish of the great sea, exceeding many.", "bsb": "Fishermen will stand by the shore; from En-gedi to En-eglaim they will spread their nets to catch fish of many kinds, like the fish of the Great Sea.", "asv": "And it shall come to pass, that fishers shall stand by it: from En-gedi even unto En-eglaim shall be a place for the spreading of nets; their fish shall be after their kinds, as the fish of the great sea, exceeding many.", "ylt": "And it hath come to pass, fishers do stand by it, from En-Gedi even unto En-Eglaim; a spreading place of nets they are; according to their own kind is their fish, as the fish of the great sea, very many.", "dra": "And the fishers shall stand over these waters, from Engaddi even to Engallim there shall be drying of nets: there shall be many sorts of the fishes thereof, as the fishes of the great sea, a very great multitude:", "bbe": "And fishermen will take up their places by it: from En-gedi as far as En-eglaim will be a place for the stretching out of nets; the fish will be of every sort, like the fish of the Great Sea, a very great number.", "geneva": "And then the fishers shall stand vpon it, and from En-gedi euen vnto En-eglaim, they shall spread out their nettes: for their fish shalbe according to their kindes, as the fishe of the maine sea, exceeding many.", "wycliffe": "And fisshers schulen stonde on tho watris; fro Engaddi `til to Engallym schal be driyng of nettis; ful many kyndis of fischis therof schulen be, as the fischis of the greet see, of ful greet multitude;", "rotherham": "And it shall come to pass that there shall stand by it fishers, from En-gedi even unto En-eglaim, places for spreading out nets, shall they be,—after their kind, shall be their fish, like the fish of the great sea exceeding many.", "darby": "And it shall come to pass, that fishers shall stand upon it; from En-gedi even unto En-eglaim shall be [a place] to spread forth nets: their fish shall be according to their kinds, as the fish of the great sea, exceeding many.", "twenty": "", "jps": "And it shall come to pass, that fishers shall stand by it from En-gedi even unto En-eglaim; there shall be a place for the spreading of nets; their fish shall be after their kinds, as the fish of the Great Sea, exceeding many.", "acv": "And it shall come to pass, that fishermen shall stand by it. From En-gedi even to En-eglaim shall be a place for the spreading of nets. Their fish shall be according to their kinds, as the fish of the great sea, very many.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass that fishers shall stand upon it; from En-gedi to En-eglaim shall be places to spread nets; and therein shall be fish according to their kinds, like the fish of the great sea, exceeding many.", "webster": "And it shall come to pass, [that] the fishers shall stand upon it from En-gedi even to En-eglaim; they shall be a [place] to spread forth nets; their fish shall be according to their kinds, as the fish of the great sea, very numerous.", "vulgate": "vivent et stabunt super illa piscatores ab Engaddi usque ad Engallim siccatio sagenarum erunt plurimae species erunt piscium eius sicut pisces maris magni multitudinis nimiae;", "brenton": "And fishers shall stand there from Ingadin to Enagallim; it shall be a place to spread out nets upon; it shall be distinct; and the fishes thereof shall be as the fishes of the great sea, a very great multitude."}}, {"v": 11, "ref": "47:11", "o": "בצאת/ו בִּצֹּאתָ֧י/ו וּ/גְבָאָ֛י/ו וְ/לֹ֥א יֵרָפְא֖וּ לְ/מֶ֥לַח נִתָּֽנוּ", "en": {"kjv": "But the miry places thereof and the marishes thereof shall not be healed; they shall be given to salt.", "web": "But the miry places of it, and its marshes, shall not be healed; they shall be given up to salt.", "bsb": "But the swamps and marshes will not become fresh; they will be left for salt.", "asv": "But the miry places thereof, and the marshes thereof, shall not be healed; they shall be given up to salt.", "ylt": "Its miry and its marshy places--they are not healed; to salt they have been given up.", "dra": "But on the shore thereof, and in the fenny places they shall not be healed, because they shall be turned into saltpits.", "bbe": "The wet places and the pools will not be made sweet; they will be given up to salt.", "geneva": "But the myrie places thereof, and the marises thereof shall not be wholesome: they shalbe made salt pittes.", "wycliffe": "but in brynkis therof and in maraisis watris shulen not be heelid, for tho `schulen be youun in to places of makynge of salt.", "rotherham": "the swamps thereof and the pools thereof, shall not be healed to salt, have they been given up.", "darby": "But its marshes and its pools shall not be healed; they shall be given up to salt.", "twenty": "", "jps": "But the miry places thereof, and the marshes thereof, shall not be healed; they shall be given for salt.", "acv": "But the miry places of it, and the marshes of it, shall not be healed. They shall be given up to salt.", "anderson": "", "haweis": "", "noyes": "But the miry places thereof, and the marshes thereof, shall not be healed; they shall be appointed for salt.", "webster": "But its miry places and its marshes shall not be healed; they shall be given to salt.", "vulgate": "in litoribus autem eius et in palustribus non sanabuntur quia in salinas dabuntur;", "brenton": "But at the outlet of the water, and the turn of it, and where it overflows its banks, they shall not heal at all; they are given to salt."}}, {"v": 12, "ref": "47:12", "o": "וְ/עַל הַ/נַּ֣חַל יַעֲלֶ֣ה עַל שְׂפָת֣/וֹ מִ/זֶּ֣ה וּ/מִ/זֶּ֣ה כָּל עֵֽץ מַ֠אֲכָל לֹא יִבּ֨וֹל עָלֵ֜/הוּ וְ/לֹֽא יִתֹּ֣ם פִּרְי֗/וֹ לָֽ/חֳדָשָׁי/ו֙ יְבַכֵּ֔ר כִּ֣י מֵימָ֔י/ו מִן הַ/מִּקְדָּ֖שׁ הֵ֣מָּה יֽוֹצְאִ֑ים ו/היו וְ/הָיָ֤ה פִרְי/וֹ֙ לְ/מַֽאֲכָ֔ל וְ/עָלֵ֖/הוּ לִ/תְרוּפָֽה", "en": {"kjv": "And by the river upon the bank thereof, on this side and on that side, shall grow all trees for meat, whose leaf shall not fade, neither shall the fruit thereof be consumed: it shall bring forth new fruit according to his months, because their waters they issued out of the sanctuary: and the fruit thereof shall be for meat, and the leaf thereof for medicine.", "web": "By the river on its bank, on this side and on that side, shall grow every tree for food, whose leaf shall not wither, neither shall its fruit fail: it shall produce new fruit every month, because its waters issue out of the sanctuary; and its fruit shall be for food, and its leaf for healing.", "bsb": "Along both banks of the river, fruit trees of all kinds will grow. Their leaves will not wither, and their fruit will not fail. Each month they will bear fruit, because the water from the sanctuary flows to them. Their fruit will be used for food and their leaves for healing.”", "asv": "And by the river upon the bank thereof, on this side and on that side, shall grow every tree for food, whose leaf shall not wither, neither shall the fruit thereof fail: it shall bring forth new fruit every month, because the waters thereof issue out of the sanctuary; and the fruit thereof shall be for food, and the leaf thereof for healing.", "ylt": "And by the stream there cometh up on its edge, on this side and on that side, every kind of fruit-tree whose leaf fadeth not, and not consumed is its fruit, according to its months it yieldeth first-fruits, because its waters from the sanctuary are coming forth; and its fruits hath been for food, and its leaf for medicine.", "dra": "And by the torrent on the banks thereof on both sides shall grow all trees that bear fruit: their leaf shall not fall off, and their fruit shall not fail: every month shall they bring forth firstfruits, because the waters thereof shall issue out of the sanctuary: and the fruits thereof shall be for food, and the leaves thereof for medicine.", "bbe": "And by the edge of the river, on this side and on that, will come up every tree used for food, whose leaves will ever be green and its fruit will not come to an end: it will have new fruit every month, because its waters come out from the holy place: the fruit will be for food and the leaf will make well those who are ill.", "geneva": "And by this riuer vpon the brinke thereof, on this side, and on that side shall grow all fruitful trees, whose leafe shall not fade, neither shall ye fruit thereof faile: it shall bring forth new fruit according to his moneths, because their waters run out of ye Sanctuarie: and the fruite thereof shalbe meat, and the leafe thereof shalbe for medicine.", "wycliffe": "And ech tree berynge fruit schal growe on the stronde, in the ryueris therof on ech side; a leef therof schal not falle doun, and the fruyt therof schal not faile; bi alle monethis it schal bere firste fruytis, for the watris therof schulen go out of the seyntuarie; and the fruytis therof schulen be in to mete, and the leeuys therof to medicyn.", "rotherham": "And, by the river, shall grow up on the bank thereof on this side and on that side every tree for food the leaf whereof, shall not fade, neither shall fail the fruit thereof, by its months, shall it break forth, for, as for the waters thereof, out of the sanctuary, are they coming forth,—and the fruit thereof shall be, for food, and, the leaf thereof, for healing.", "darby": "And by the river, upon its bank, on the one side and on the other, shall grow all trees for food, whose leaf shall not fade, nor their fruit fail: it shall bring forth new fruit every month, for its waters issue out of the sanctuary; and the fruit thereof shall be for food, and the leaf thereof for medicine.", "twenty": "", "jps": "And by the river upon the bank thereof, on this side and on that side, shall grow every tree for food, whose leaf shall not wither, neither shall the fruit thereof fail; it shall bring forth new fruit every month, because the waters thereof issue out of the sanctuary; and the fruit thereof shall be for food, and the leaf thereof for healing.'", "acv": "And by the river upon the bank of it, on this side and on that side, shall grow every tree for food, whose leaf shall not wither, nor shall the fruit of it fail. It shall bring forth new fruit every month, because the waters of it issue out of the sanctuary. And the fruit of it shall be for food, and the leaf of it for healing.", "anderson": "", "haweis": "", "noyes": "And by the river, upon the bank thereof, on this side and on that side, shall grow all trees for food, whose leaf shall not fade, and whose fruit shall not fail; every month shall they bring forth new fruit; because their waters issue forth from the sanctuary. And their fruit shall be for food, and their leaves for medicine.", "webster": "And by the river upon its bank, on this side and on that side, shall grow all trees for food, whose leaf shall not fade, neither shall its fruit be consumed: it shall bring forth new fruit according to its months, because their waters they issued out of the sanctuary: and its fruit shall be for food, and its leaf for medicine.", "vulgate": "et super torrentem orietur in ripis eius ex utraque parte omne lignum pomiferum non defluet folium ex eo et non deficiet fructus eius per singulos menses adferet primitiva quia aquae eius de sanctuario egredientur et erunt fructus eius in cibum et folia eius ad medicinam;", "brenton": "And every fruit tree shall grow by the river, even on the bank of it on this side and on that side: they shall not decay upon it, neither shall their fruit fail: they shall bring forth the first-fruit of their early crop, for these their waters come forth of the sanctuary: and their fruit shall be for meat, and their foliage for health."}}, {"v": 13, "ref": "47:13", "o": "כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה גֵּ֤ה גְבוּל֙ אֲשֶׁ֣ר תִּתְנַחֲל֣וּ אֶת הָ/אָ֔רֶץ לִ/שְׁנֵ֥י עָשָׂ֖ר שִׁבְטֵ֣י יִשְׂרָאֵ֑ל יוֹסֵ֖ף חֲבָלִֽים", "en": {"kjv": "Thus saith the Lord God; This shall be the border, whereby ye shall inherit the land according to the twelve tribes of Israel: Joseph shall have two portions.", "web": "Thus says the Lord Yahweh: This shall be the border, by which you shall divide the land for inheritance according to the twelve tribes of Israel: Joseph shall have two portions.", "bsb": "This is what the Lord GOD says: “These are the boundaries by which you are to divide the land as an inheritance among the twelve tribes of Israel; Joseph shall receive two portions.", "asv": "Thus saith the Lord Jehovah: This shall be the border, whereby ye shall divide the land for inheritance according to the twelve tribes of Israel: Joseph shall have two portions.", "ylt": "`Thus said the Lord Jehovah: This is the border whereby ye inherit the land, according to the twelve tribes of Israel; Joseph hath portions.", "dra": "Thus saith the Lord God: This is the border, by which you shall possess the land according to the twelve tribes of Israel: for Joseph hath a double portion.", "bbe": "This is what the Lord has said: These are the limits by which you will take up your heritage in the land among the twelve tribes of Israel: Joseph is to have two parts.", "geneva": "Thus saith the Lord God, This shall be the border, whereby ye shall inherite the lande according to the twelue tribes of Israel: Ioseph shall haue two portions.", "wycliffe": "The Lord God seith these thingis, This is the ende, in which ye schulen welde the lond, in the twelue lynagis of Israel; for Joseph hath double part.", "rotherham": "Thus saith My Lord Yahweh, This shall be the boundary whereby ye shall take your inheritances in the land, according to the twelve tribes of Israel,—Joseph shall have portions.", "darby": "Thus saith the Lord Jehovah: This shall be the border whereby ye shall allot the land as inheritance according to the twelve tribes of Israel: Joseph [shall have two] portions.", "twenty": "", "jps": "Thus saith the L-rd GOD: 'This shall be the border, whereby ye shall divide the land for inheritance according to the twelve tribes of Israel, Joseph receiving two portions.", "acv": "Thus says the lord Jehovah: This shall be the border by which ye shall divide the land for inheritance according to the twelve tribes of Israel. Joseph shall have two portions.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: This is the border, according to which ye shall distribute the land among the twelve tribes of Israel. Joseph shall have two portions.", "webster": "Thus saith the Lord GOD; This [shall be] the border, by which ye shall inherit the land according to the twelve tribes of Israel: Joseph [shall have two] portions.", "vulgate": "haec dicit Dominus Deus hic est terminus in quo possidebitis terram in duodecim tribubus Israhel quia Ioseph duplicem funiculum habet;", "brenton": "Thus saith the Lord God; Ye shall inherit these borders of the land; they are given by lot to the twelve tribes of the children of Israel."}}, {"v": 14, "ref": "47:14", "o": "וּ/נְחַלְתֶּ֤ם אוֹתָ/הּ֙ אִ֣ישׁ כְּ/אָחִ֔י/ו אֲשֶׁ֤ר נָשָׂ֨אתִי֙ אֶת יָדִ֔/י לְ/תִתָּ֖/הּ לַ/אֲבֹֽתֵי/כֶ֑ם וְ/נָ֨פְלָ֜ה הָ/אָ֧רֶץ הַ/זֹּ֛את לָ/כֶ֖ם בְּ/נַחֲלָֽה", "en": {"kjv": "And ye shall inherit it, one as well as another: concerning the which I lifted up mine hand to give it unto your fathers: and this land shall fall unto you for inheritance.", "web": "You shall inherit it, one as well as another; for I swore to give it to your fathers: and this land shall fall to you for inheritance.", "bsb": "You are to divide it equally among them. Because I swore with an uplifted hand to give it to your forefathers, this land will fall to you as an inheritance.", "asv": "And ye shall inherit it, one as well as another; for I sware to give it unto your fathers: and this land shall fall unto you for inheritance.", "ylt": "And ye have inherited it, one as well as another, in that I have lifted up My hand to give it to your fathers; and this land hath fallen to you in inheritance.", "dra": "And you shall possess it, every man in like manner as his brother: concerning which I lifted up my hand to give it to your fathers: and this land shall fall unto you for a possession.", "bbe": "And you are to make an equal division of it; as I gave my oath to your fathers to give it to you: for this land is to be your heritage.", "geneva": "And ye shall inherite it, one as well as another: concerning the which I lift vp mine hand to giue it vnto your fathers, and this lande shall fall vnto you for inheritance.", "wycliffe": "Forsothe ye schulen welde it, ech man euenli as his brother; on which Y reiside myn hond, that Y schulde yyue to youre fadris; and this lond schal falle to you in to possessioun.", "rotherham": "so shall ye inherit it each man like his brother, as to which I lifted my hand to give it to your fathers,—so shall this land fall to you as an inheritance.", "darby": "And ye shall inherit it, one as well as another, [the land] concerning which I lifted up my hand to give it unto your fathers; and this land shall fall to you for inheritance.", "twenty": "", "jps": "And ye shall inherit it, one as well as another, concerning which I lifted up My hand to give it unto your fathers; and this land shall fall unto you for inheritance.", "acv": "And ye shall inherit it, one as well as another, for I swore to give it to your fathers. And this land shall fall to you for inheritance.", "anderson": "", "haweis": "", "noyes": "And ye shall inherit it, one like another. For I have lifted up my hand, that I would give it to your fathers; and this land shall fall to you for an inheritance.", "webster": "And ye shall inherit it, one as well as another: [concerning] which I lifted up my hand to give it to your fathers: and this land shall fall to you for inheritance.", "vulgate": "possidebitis autem eam singuli aeque ut frater suus quam levavi manum meam ut darem patribus vestris et cadet terra haec vobis in possessionem;", "brenton": "And ye shall inherit it, each according to his brother's portion, even the land concerning which I lifted up my hand to give it to your fathers: and this land shall fall to you by lot."}}, {"v": 15, "ref": "47:15", "o": "וְ/זֶ֖ה גְּב֣וּל הָ/אָ֑רֶץ לִ/פְאַ֨ת צָפ֜וֹנָ/ה מִן הַ/יָּ֧ם הַ/גָּד֛וֹל הַ/דֶּ֥רֶךְ חֶתְלֹ֖ן לְב֥וֹא צְדָֽדָ/ה", "en": {"kjv": "And this shall be the border of the land toward the north side, from the great sea, the way of Hethlon, as men go to Zedad;", "web": "This shall be the border of the land: On the north side, from the great sea, by the way of Hethlon, to the entrance of Zedad;", "bsb": "This shall be the boundary of the land:", "asv": "And this shall be the border of the land: On the north side, from the great sea, by the way of Hethlon, unto the entrance of Zedad;", "ylt": "`And this is the border of the land at the north quarter; from the great sea, the way of Hethlon, at the coming in to Zedad:", "dra": "And this is the border of the land: toward the north side, from the great sea by the way of Hethalon, as men go to Sedada,", "bbe": "And this is to be the limit of the land: on the north side, from the Great Sea, in the direction of Hethlon, as far as the way into Hamath;", "geneva": "And this shall be the border of the lande towarde the North side, from the maine sea toworde Hethlon as men goe to Zedadah:", "wycliffe": "This is the ende of the lond at the north coost fro the grete see, the weie of Bethalon to men comynge to Sedala,", "rotherham": "This then shall be the boundary of the land,—on the north side, from the great sea by the way of Hethlon to the entering, in of Zedad;", "darby": "And this shall be the border of the land: toward the north side, from the great sea, the way of Hethlon, as one goeth to Zedad,", "twenty": "", "jps": "And this shall be the border of the land: on the north side, from the Great Sea, by the way of Hethlon, unto the entrance of Zedad;", "acv": "And this shall be the border of the land: On the north side, from the great sea, by the way of Hethlon, to the entrance of Zedad,", "anderson": "", "haweis": "", "noyes": "And this shall be the border of the land toward the north side: from the great sea toward the way of Hethlon, as men go to Zedad,", "webster": "And this [shall be] the border of the land towards the north side, from the great sea, the way of Hethlon, as men go to Zedad;", "vulgate": "hic est autem terminus terrae ad plagam septentrionalem a mari magno via Bethalon venientibus Sadada;", "brenton": "And these are the borders of the land that lies northward, from the great sea that comes down, and divides the entrance of Emaseldam;"}}, {"v": 16, "ref": "47:16", "o": "חֲמָ֤ת בֵּר֨וֹתָה֙ סִבְרַ֔יִם אֲשֶׁר֙ בֵּין גְּב֣וּל דַּמֶּ֔שֶׂק וּ/בֵ֖ין גְּב֣וּל חֲמָ֑ת חָצֵר֙ הַתִּיכ֔וֹן אֲשֶׁ֖ר אֶל גְּב֥וּל חַוְרָֽן", "en": {"kjv": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazar–hatticon, which is by the coast of Hauran.", "web": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazer Hatticon, which is by the border of Hauran.", "bsb": "On the north side it will extend from the Great Sea by way of Hethlon through Lebo-hamath to Zedad, Berothah, and Sibraim (which is on the border between Damascus and Hamath), as far as Hazer-hatticon, which is on the border of Hauran.", "asv": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazer-hatticon, which is by the border of Hauran.", "ylt": "Hamath, Berothah, Sibraim, that is between the border of Damascus and the border of Hamath; Hazar-Hatticon, that is at the coast of Havran.", "dra": "Emath, Berotha, Sabarim, which is between the border of Damascus and the border of Emath the house of Tichon, which is by the border of Auran.", "bbe": "To Zedad, Berothah, Sibraim, which is between the limit of Damascus and the limit of Hazar-hatticon, which is on the limit of Hauran.", "geneva": "Hamath, Berothah, Sibraim, which is betweene the border of Damascus, and the border of Hamath, and Hazar, Hatticon, which is by the coast of Hauran.", "wycliffe": "Emath, Beroth, Sabarym, which is in the myddis bitwixe Damask and niy coostis of Emath, the hous of Thichon, which is bisidis the endis of Auran.", "rotherham": "Hamath Berothah, Sibraim, which is between the boundary of Damascus and the boundary of Hamath,—Hazer-hatticon, which is by the boundary of Hauran.", "darby": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazer-hatticon, which is by the border of Hauran.", "twenty": "", "jps": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazer-hatticon, which is by the border of Hauran.", "acv": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath, Hazer-hatticon, which is by the border of Hauran.", "anderson": "", "haweis": "", "noyes": "Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath, and Hazar-hatticon, which is by the coast of Hauran.", "webster": "Hamath, Berothah, Sibraim, which [is] between the border of Damascus and the border of Hamath; Hazar-hatticon, which [is] by the border of Hauran.", "vulgate": "Emath Berotha Sabarim quae est inter terminum Damasci et confinium Emath domus Atticon quae est iuxta terminos Auran;", "brenton": "Maabthera, Ebrameliam, between the coasts of Damascus and the coasts of Emathi, the habitation of Saunan, which places are above the coasts of Auranitis."}}, {"v": 17, "ref": "47:17", "o": "וְ/הָיָ֨ה גְב֜וּל מִן הַ/יָּ֗ם חֲצַ֤ר עֵינוֹן֙ גְּב֣וּל דַּמֶּ֔שֶׂק וְ/צָפ֥וֹן צָפ֖וֹנָ/ה וּ/גְב֣וּל חֲמָ֑ת וְ/אֵ֖ת פְּאַ֥ת צָפֽוֹן", "en": {"kjv": "And the border from the sea shall be Hazar–enan, the border of Damascus, and the north northward, and the border of Hamath. And this is the north side.", "web": "The border from the sea, shall be Hazar Enon at the border of Damascus; and on the north northward is the border of Hamath. This is the north side.", "bsb": "So the border will run from the Sea to Hazar-enan, along the northern border of Damascus, with the territory of Hamath to the north. This will be the northern boundary.", "asv": "And the border from the sea, shall be Hazar-enon at the border of Damascus; and on the north northward is the border of Hamath. This is the north side.", "ylt": "And the border from the sea hath been Hazar-Enan, the border of Damascus, and Zaphon at the north, and the border of Hamath: and this is the north quarter.", "dra": "And the border from the sea even to the court of Enan, shall be the border of Damascus, and from the north to the north: the border of Emath, this is the north side.", "bbe": "And this is the limit from the sea in the direction of Hazar-enon; and the limit of Damascus is to the north, and on the north is the limit of Hamath. This is the north side.", "geneva": "And the border from the sea shalbe Hazar, Enan, and the border of Damascus, and the residue of the North, Northwarde, and the border of Hamath: so shalbe the North part.", "wycliffe": "And the ende schal be fro the see `til to the porche of Ennon, the ende of Damask, and fro the north til to the north, the ende of Emath; forsothe this is the north coost.", "rotherham": "Thus shall there be a boundary, from the sea Hazar-enin the boundary of Damascus, even the north northward and the boundary of Hamath,—even the north, side.", "darby": "And the border from the sea shall be Hazar-enan, the border of Damascus, and the north northward, and the border of Hamath: this is the north side.", "twenty": "", "jps": "And the border from the sea shall be Hazar-enon at the border of Damascus, and on the north northward is the border of Hamath. This is the north side.", "acv": "And the border from the sea, shall be Hazar-enon at the border of Damascus, and on the north northward is the border of Hamath. This is the north side.", "anderson": "", "haweis": "", "noyes": "And the border from the sea shall be Hazar-Enon, the border of Damascus and farther northward, and the border of Hamath.", "webster": "And the border from the sea shall be Hazar-enan, the border of Damascus, and the north northward, and the border of Hamath. And [this is] the north side.", "vulgate": "et erit terminus a mari usque ad atrium Aenon terminus Damasci et ab aquilone ad aquilonem et terminus Emath plaga autem septentrionalis;", "brenton": "These are the borders from the sea, from the habitations of Aenan, the coasts of Damascus, and the northern coasts."}}, {"v": 18, "ref": "47:18", "o": "וּ/פְאַ֣ת קָדִ֡ים מִ/בֵּ֣ין חַוְרָ֣ן וּ/מִ/בֵּין דַּמֶּשֶׂק֩ וּ/מִ/בֵּ֨ין הַ/גִּלְעָ֜ד וּ/מִ/בֵּ֨ין אֶ֤רֶץ יִשְׂרָאֵל֙ הַ/יַּרְדֵּ֔ן מִ/גְּב֛וּל עַל הַ/יָּ֥ם הַ/קַּדְמוֹנִ֖י תָּמֹ֑דּוּ וְ/אֵ֖ת פְּאַ֥ת קָדִֽימָ/ה", "en": {"kjv": "And the east side ye shall measure from Hauran, and from Damascus, and from Gilead, and from the land of Israel by Jordan, from the border unto the east sea. And this is the east side.", "web": "The east side, between Hauran and Damascus and Gilead, and the land of Israel, shall be the Jordan; from the north border to the east sea you shall measure. This is the east side.", "bsb": "On the east side the border will run between Hauran and Damascus, along the Jordan between Gilead and the land of Israel, to the Eastern Sea and as far as Tamar. This will be the eastern boundary.", "asv": "And the east side, between Hauran and Damascus and Gilead, and the land of Israel, shall be the Jordan; from the north border, unto the east sea shall ye measure. This is the east side.", "ylt": "`And the east quarter is from between Havran, and Damascus, and Gilead, and the land of Israel, to the Jordan; from the border over-against the eastern sea ye measure: and this is the east quarter.", "dra": "And the east side is from the midst of Auran, and from the midst of Damascus, and from the midst of Galaad, and from the midst of the land of Israel, Jordan making the bound to the east sea, and thus you shall measure the east side.", "bbe": "And the east side will be from Hazar-enon, which is between Hauran and Damascus; and between Gilead and the land of Israel the Jordan will be the limit, to the east sea, to Tamar. This is the east side.", "geneva": "But the East side shall ye measure from Hauran, and from Damascus, and from Gilead, and from the lande of Israel by Iorden, and from the border vnto the East sea: and so shalbe the East part.", "wycliffe": "Certis the eest coost fro the myddis of Auran, and fro the myddis of Damask, and fro the myddis of Galaad, and fro the myddis of the lond of Israel, is Jordan departynge at the eest see, also ye schulen mete the eest coost.", "rotherham": "And for the east side, from between Hauran and Damascus and from between Gilead and the land of Israel the Jordan, from the boundary by the sea eastward, shall ye measure—even the east side.", "darby": "— And on the east side ye shall measure between Hauran and Damascus, and Gilead and the land of Israel [by] the Jordan, from the border unto the east sea: this is the east side.", "twenty": "", "jps": "And the east side, between Hauran and Damascus and Gilead, and the land of Israel, by the Jordan, from the border unto the east sea shall ye measure. This is the east side.", "acv": "And the east side, between Hauran and Damascus and Gilead, and the land of Israel, shall be the Jordan, from the north border to the east sea ye shall measure. This is the east side.", "anderson": "", "haweis": "", "noyes": "This is the north side. And the east side ye shall measure between Hauran and Damascus, and between Gilead and the land of Israel by the Jordan, from the border to the east sea. This is the east side.", "webster": "And the east side ye shall measure from Hauran, and from Damascus, and from Gilead, and from the land of Israel [by] Jordan, from the border to the east sea. And [this is] the east side.", "vulgate": "porro plaga orientalis de medio Auran et de medio Damasci et de medio Galaad et de medio terrae Israhel Iordanis disterminans ad mare orientale metiemini etiam plagam orientalem;", "brenton": "And the eastern coasts between Loranitis, and Damascus, and the land of Galaad, and the land of Israel, the Jordan divides to the sea that is east of the city of palm-trees. These are the eastern coasts."}}, {"v": 19, "ref": "47:19", "o": "וּ/פְאַת֙ נֶ֣גֶב תֵּימָ֔נָ/ה מִ/תָּמָ֗ר עַד מֵי֙ מְרִיב֣וֹת קָדֵ֔שׁ נַחֲלָ֖ה אֶל הַ/יָּ֣ם הַ/גָּד֑וֹל וְ/אֵ֥ת פְּאַת תֵּימָ֖נָ/ה נֶֽגְבָּ/ה", "en": {"kjv": "And the south side southward, from Tamar even to the waters of strife in Kadesh, the river to the great sea. And this is the south side southward.", "web": "The south side southward shall be from Tamar as far as the waters of Meriboth Kadesh, to the brook, to the great sea. This is the south side southward.", "bsb": "On the south side it will run from Tamar to the waters of Meribath-kadesh, and along the Brook of Egypt to the Great Sea. This will be the southern boundary.", "asv": "And the south side southward shall be from Tamar as far as the waters of Meriboth-kadesh, to the brook of Egypt, unto the great sea. This is the south side southward.", "ylt": "`And the south quarter southward is from Tamar unto the waters of Meriboth-Kadesh, the stream unto the great sea: and this is the south quarter southward.", "dra": "And the south side southward is, from Thamar even to the waters of contradiction of Cades: and, the torrent even to the great sea: and this is the south side southward.", "bbe": "And the south side to the south will be from Tamar as far as the waters of Meribath-kadesh, to the stream of Egypt, to the Great Sea. This is the south side, on the south.", "geneva": "And the Southside shalbe towarde Teman from Tamar to the waters of Meriboth in Kadesh, and the riuer to the maine sea: so shalbe the South part towarde Teman.", "wycliffe": "Forsothe the south coost of myddai is fro Thamar til to the watris of ayenseiyng of Cades; and the stronde til to the greet see, and the south coost at myddai.", "rotherham": "And for the south side southward, from Tamar as far as the waters of Meriboth-kadesh, towards the torrent bed unto the great sea,—even the south side southward.", "darby": "— And the south side southward, from Tamar to the waters of Meribah-Kadesh, by the torrent, unto the great sea: this is the south side southward.", "twenty": "", "jps": "And the south side southward shall be from Tamar as far as the waters of Meriboth-kadesh, to the Brook, unto the Great Sea. This is the south side southward.", "acv": "And the south side southward shall be from Tamar as far as the waters of Meriboth-kadesh, to the brook of Egypt, to the great sea. This is the south side southward.", "anderson": "", "haweis": "", "noyes": "And the south side southward shall be from Tamar to the waters of strife in Kadesh, as far as the river by the great sea.", "webster": "And the south side southward, from Tamar [even] to the waters of strife [in] Kadesh, the river to the great sea. And [this is] the south side southward.", "vulgate": "plaga autem australis meridiana a Thamar usque ad aquas Contradictionis Cades et torrens usque ad mare magnum et plaga ad meridiem australis;", "brenton": "And the southern and south-western coasts are from Thaeman and the city of palm-trees, to the water of Marimoth Cadem, reaching forth to the great sea. This part is the south and south-west."}}, {"v": 20, "ref": "47:20", "o": "וּ/פְאַת יָם֙ הַ/יָּ֣ם הַ/גָּד֔וֹל מִ/גְּב֕וּל עַד נֹ֖כַח לְב֣וֹא חֲמָ֑ת זֹ֖את פְּאַת יָֽם", "en": {"kjv": "The west side also shall be the great sea from the border, till a man come over against Hamath. This is the west side.", "web": "The west side shall be the great sea, from the south border as far as over against the entrance of Hamath. This is the west side.", "bsb": "And on the west side, the Great Sea will be the boundary up to a point opposite Lebo-hamath. This will be the western boundary.", "asv": "And the west side shall be the great sea, from the south border as far as over against the entrance of Hamath. This is the west side.", "ylt": "`And the west quarter is the great sea, from the border till over-against the coming in to Hamath: this is the west quarter.", "dra": "And the side toward the sea, is the great sea from the borders straight on, till thou come to Emath: this is the side of the sea.", "bbe": "And the west side will be the Great Sea, from the limit on the south to a point opposite the way into Hamath. This is the west side.", "geneva": "The West parte also shalbe the great sea from the border, till a man come ouer against Hamath: this shalbe the West part.", "wycliffe": "And the coost of the see is the greet see, fro the niy coost bi streiyt, til thou come to Emath; this is the coost of the see.", "rotherham": "And for the west side, the great sea, from the boundary as far as over against the entering in of Hamath— this is the west side.", "darby": "— And the west side shall be the great sea from the border, as far as over against the entering into Hamath: this is the west side.", "twenty": "", "jps": "And the west side shall be the Great Sea, from the border as far as over against the entrance of Hamath. This is the west side.", "acv": "And the west side shall be the great sea, from the south border as far as opposite the entrance of Hamath. This is the west side.", "anderson": "", "haweis": "", "noyes": "This is the south side southward. And the west side shall be the great sea, from the border till a man come over against Hamath. This is the west side.", "webster": "The west side also [shall be] the great sea from the border, till a man cometh over against Hamath. This [is] the west side.", "vulgate": "et plaga maris mare magnum a confinio per directum donec venias Emath haec est plaga maris;", "brenton": "This part of the great sea forms a border, till one comes opposite the entrance of Emath, even as far as the entrance thereof. These are the parts west of Emath."}}, {"v": 21, "ref": "47:21", "o": "וְ/חִלַּקְתֶּ֞ם אֶת הָ/אָ֧רֶץ הַ/זֹּ֛את לָ/כֶ֖ם לְ/שִׁבְטֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "So shall ye divide this land unto you according to the tribes of Israel.", "web": "So you shall divide this land to you according to the tribes of Israel.", "bsb": "You are to divide this land among yourselves according to the tribes of Israel.", "asv": "So shall ye divide this land unto you according to the tribes of Israel.", "ylt": "`And ye have divided this land to you, according to the tribes of Israel;", "dra": "And you shall divide this land unto you by the tribes of Israel:", "bbe": "You will make a division of the land among you, tribe by tribe.", "geneva": "So shall ye deuide this lande vnto you, according to the tribes of Israel.", "wycliffe": "And ye schulen departe this lond to you bi the lynagis of Israel;", "rotherham": "So then ye shall apportion this land to you by the tribes of Israel. —", "darby": "And ye shall divide this land unto you according to the tribes of Israel.", "twenty": "", "jps": "So shall ye divide this land unto you according to the tribes of Israel.", "acv": "So ye shall divide this land to you according to the tribes of Israel.", "anderson": "", "haweis": "", "noyes": "So shall ye divide this land among you, according to the tribes of Israel.", "webster": "So shall ye divide this land to you according to the tribes of Israel.", "vulgate": "et dividetis terram istam vobis per tribus Israhel;", "brenton": "So ye shall divide this land to them, even to the tribes of Israel."}}, {"v": 22, "ref": "47:22", "o": "וְ/הָיָ֗ה תַּפִּ֣לוּ אוֹתָ/הּ֮ בְּ/נַחֲלָה֒ לָ/כֶ֗ם וּ/לְ/הַ/גֵּרִים֙ הַ/גָּרִ֣ים בְּ/תוֹכְ/כֶ֔ם אֲשֶׁר הוֹלִ֥דוּ בָנִ֖ים בְּ/תֽוֹכְ/כֶ֑ם וְ/הָי֣וּ לָ/כֶ֗ם כְּ/אֶזְרָח֙ בִּ/בְנֵ֣י יִשְׂרָאֵ֔ל אִתְּ/כֶם֙ יִפְּל֣וּ בְ/נַחֲלָ֔ה בְּ/ת֖וֹךְ שִׁבְטֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And it shall come to pass, that ye shall divide it by lot for an inheritance unto you, and to the strangers that sojourn among you, which shall beget children among you: and they shall be unto you as born in the country among the children of Israel; they shall have inheritance with you among the tribes of Israel.", "web": "It shall happen, that you shall divide it by lot for an inheritance to you and to the aliens who live among you, who shall father children among you; and they shall be to you as the native-born among the children of Israel; they shall have inheritance with you among the tribes of Israel.", "bsb": "You shall allot it as an inheritance for yourselves and for the foreigners who dwell among you and who have children. You are to treat them as native-born Israelites; along with you, they shall be allotted an inheritance among the tribes of Israel.", "asv": "And it shall come to pass, that ye shall divide it by lot for an inheritance unto you and to the strangers that sojourn among you, who shall beget children among you; and they shall be unto you as the home-born among the children of Israel; they shall have inheritance with you among the tribes of Israel.", "ylt": "and it hath come to pass, ye separate it for an inheritance to yourselves, and to the sojourners who are sojourning in your midst, who have begotten sons in your midst, and they have been to you as native, with the sons of Israel, with you they are separated for an inheritance in the midst of the tribes of Israel.", "dra": "And you shall divide it by lot for an inheritance to you, and to the strangers that shall come over to you, that shall beget children among you: and they shall be unto you as men of the same country born among the children of Israel: they shall divide the possession with you in the midst of the tribes of Israel.", "bbe": "And you are to make a distribution of it, by the decision of the Lord, for a heritage to you and to the men from other lands who are living among you and who have children in your land: they will be the same to you as if they were Israelites by birth, they will have their heritage with you among the tribes of Israel.", "geneva": "And you shall deuide it by lot for an inheritance vnto you, and to the strangers that dwell among you, which shall beget children among you, and they shall be vnto you, as borne in the countrey among the children of Israel, they shall part inheritance with you in the middes of the tribes of Israel.", "wycliffe": "and ye schulen sende it in to eritage to you, and to comelyngis that comen to you, that gendriden sones in the myddis of you; and thei schulen be to you as men borun in the lond among the sones of Israel; with you thei schulen departe possessioun, in the myddis of the lynages of Israel.", "rotherham": "And it shall come to pass that ye shall divide it by lot as an inheritance, to yourselves and to the sojourners who are sojourning in your midst, who have begotten children in your midst,—so shall they be to you as a native among the sons of Israel with you, shall they cast lots for an inheritance, in the midst of the tribes of Israel.", "darby": "And it shall come to pass that ye shall divide it by lot for an inheritance unto you, and to the strangers that sojourn among you, who shall beget children among you; and they shall be unto you as the home-born among the children of Israel: with you shall they draw by lot inheritance among the tribes of Israel.", "twenty": "", "jps": "And it shall come to pass, that ye shall divide it by lot for an inheritance unto you and to the strangers that sojourn among you, who shall beget children among you; and they shall be unto you as the home-born among the children of Israel; they shall have inheritance with you among the tribes of Israel.", "acv": "And it shall come to pass, that ye shall divide it by lot for an inheritance to you and to the strangers who sojourn among you, who shall beget sons among you. And they shall be to you as the home-born among the sons of Israel; they shall have inheritance with you among the tribes of Israel.", "anderson": "", "haweis": "", "noyes": "And ye shall divide it by lot for an inheritance to you, and to the strangers that sojourn among you, who have begotten children among you; and they shall be to you as born in the country among the sons of Israel; they shall have an inheritance with you among the tribes of Israel.", "webster": "And it shall come to pass, [that] ye shall divide it by lot for an inheritance to you, and to the strangers that sojourn among you, which shall beget children among you: and they shall be to you as born in the country among the children of Israel; they shall have inheritance with you among the tribes of Israel.", "vulgate": "et mittetis eam in hereditatem vobis et advenis qui accesserint ad vos qui genuerint filios in medio vestrum et erunt vobis sicut indigenae inter filios Israhel vobiscum divident possessionem in medio tribuum Israhel;", "brenton": "Ye shall cast the lot upon it, for yourselves and the strangers that sojourn in the midst of you, who have begotten children in the midst of you: and they shall be to you as natives among the children of Israel; they shall eat with you in their inheritance in the midst of the tribes of Israel."}}, {"v": 23, "ref": "47:23", "o": "וְ/הָיָ֣ה בַ/שֵּׁ֔בֶט אֲשֶׁר גָּ֥ר הַ/גֵּ֖ר אִתּ֑/וֹ שָׁ֚ם תִּתְּנ֣וּ נַחֲלָת֔/וֹ נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "And it shall come to pass, that in what tribe the stranger sojourneth, there shall ye give him his inheritance, saith the Lord God.", "web": "It shall happen, that in what tribe the stranger lives, there you shall give him his inheritance, says the Lord Yahweh.", "bsb": "In whatever tribe a foreigner dwells, you are to assign his inheritance there,” declares the Lord GOD.", "asv": "And it shall come to pass, that in what tribe the stranger sojourneth, there shall ye give him his inheritance, saith the Lord Jehovah.", "ylt": "And it hath come to pass, in the tribe with which the sojourner sojourneth, there ye give his inheritance--an affirmation of the Lord Jehovah.", "dra": "And in what tribe soever the stranger shall be, there shall you give him possession, saith the Lord God.", "bbe": "In whatever tribe the man from a strange land is living, there you are to give him his heritage, says the Lord.", "geneva": "And in what tribe the stranger dwelleth, there shall ye giue him his inheritance, saith the Lord God.", "wycliffe": "Forsothe in what euer lynage a comelyng is, there ye schulen yyue possessioun to hym, seith the Lord God.", "rotherham": "And it shall be that with whatsoever tribe the sojourner hath become a sojourner, there shall ye give his inheritance, Declareth My Lord Yahweh.", "darby": "And it shall come to pass that in the tribe in which the stranger sojourneth, there shall ye give [him] his inheritance, saith the Lord Jehovah.", "twenty": "", "jps": "And it shall come to pass, that in what tribe the stranger sojourneth, there shall ye give him his inheritance, saith the L-rd GOD.", "acv": "And it shall come to pass, that in what tribe the stranger sojourns, there ye shall give him his inheritance, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass, that in what tribe the stranger sojourneth there shall ye appoint him his inheritance, saith the Lord Jehovah.", "webster": "And it shall come to pass, [that] in what tribe the stranger sojourneth, there shall ye give [him] his inheritance, saith the Lord GOD.", "vulgate": "in tribu autem quacumque fuerit advena ibi dabitis possessionem illi ait Dominus Deus;", "brenton": "And they shall be in the tribe of proselytes among the proselytes that are with them: there shall ye give them an inheritance, saith the Lord God."}}]}, {"c": 48, "verses": [{"v": 1, "ref": "48:1", "o": "וְ/אֵ֖לֶּה שְׁמ֣וֹת הַ/שְּׁבָטִ֑ים מִ/קְצֵ֣ה צָפ֡וֹנָ/ה אֶל יַ֣ד דֶּֽרֶךְ חֶתְלֹ֣ן לְֽבוֹא חֲמָ֡ת חֲצַ֣ר עֵינָן֩ גְּב֨וּל דַּמֶּ֤שֶׂק צָפ֨וֹנָ/ה֙ אֶל יַ֣ד חֲמָ֔ת וְ/הָיוּ ל֧/וֹ פְאַת קָדִ֛ים הַ/יָּ֖ם דָּ֥ן אֶחָֽד", "en": {"kjv": "Now these are the names of the tribes. From the north end to the coast of the way of Hethlon, as one goeth to Hamath, Hazar–enan, the border of Damascus northward, to the coast of Hamath; for these are his sides east and west; a portion for Dan.", "web": "Now these are the names of the tribes: From the north end, beside the way of Hethlon to the entrance of Hamath, Hazar Enan at the border of Damascus, northward beside Hamath, (and they shall have their sides east and west), Dan, one portion.", "bsb": "“Now these are the names of the tribes: At the northern frontier, Dan will have one portion bordering the road of Hethlon to Lebo-hamath and running on to Hazar-enan on the border of Damascus with Hamath to the north, and extending from the east side to the west side.", "asv": "Now these are the names of the tribes: From the north end, beside the way of Hethlon to the entrance of Hamath, Hazar-enan at the border of Damascus, northward beside Hamath (and they shall have their sides east and west), Dan, one portion.", "ylt": "And these are the names of the tribes: From the north end unto the side of the way of Hethlon, at the coming in to Hamath, Hazar-Enan, the border of Damascus northward, unto the side of Hamath, and they have been his--side east and west, Dan one,", "dra": "And these are the names of the tribes from the borders of the north, by the way of Hethalon, as they go to Emath, the court of Enan the border of Damascus northward, by the way off Emath. And from the east side thereof to the sea shall be one portion for Dan.", "bbe": "Now these are the names of the tribes: from the north end, from the west on the way of Hethlon to the way into Hamath, in the direction of Hazar-enon, with the limit of Damascus to the north, by Hamath; and on the limit from the east side to the west side: Dan, one part.", "geneva": "Now these are the names of the tribes. From the North side, to the coast towarde Hethlon, as one goeth to Hamath, Hazar, Enan, and the border of Damascus Northwarde the coast of Hamath, euen from the East side to the West shall be a portion for Dan.", "wycliffe": "And these ben the names of lynagis, fro the endis of the north, bisidis the weie Ethalon, to men goynge to Emath, the porche of Ennon, the terme of Damask, to the north bisidis Emath; and the eest coost schal be to it the see, o part schal be of Dan.", "rotherham": "Now these are the names of the tribes,—At the northern extremity, beside the Hethlon road—as one entereth Hamath, Hazar-enan the boundary of Damascus northwards by the side of Hamath, and so they shall be his as east side and west-Dan, one.", "darby": "And these are the names of the tribes: From the north end along the way of Hethlon, as one entereth into Hamath, Hazar-enan, the border of Damascus northward unto near Hamath — the east and west side [belonging] to him — shall Dan have one [portion].", "twenty": "", "jps": "Now these are the names of the tribes: from the north end, beside the way of Hethlon to the entrance of Hamath, Hazar-enan, at the border of Damascus, northward, beside Hamath; and they shall have their sides east and west: Dan, one portion.", "acv": "Now these are the names of the tribes: From the north end, beside the way of Hethlon to the entrance of Hamath, Hazar-enan at the border of Damascus, northward beside Hamath, (and they shall have their sides east and west), Dan, one portion.", "anderson": "", "haweis": "", "noyes": "And these are the names of the tribes. From the north end by the way of Hethlon, as one goeth to Hamath, Hazar-Enan, the border of Damascus northward toward Hamath; and to him belongeth from the east side to the west side: Dan, one tribe.", "webster": "Now these [are] the names of the tribes. From the north end to the border of the way of Hethlon, as one goeth to Hamath, Hazar-enan, the border of Damascus northward, to the limit of Hamath; for these are his sides east [and] west; a [portion for] Dan.", "vulgate": "et haec nomina tribuum a finibus aquilonis iuxta viam Aethlon pergentibus Emath atrium Aenon terminus Damasci ad aquilonem iuxta Emath et erit ei plaga orientalis mare Dan una;", "brenton": "And these are the names of the tribes from the northern corner, on the side of the descent that draws a line to the entrance of Emath the palace of Aelam, the border of Damascus northward on the side of Emath the palace; and they shall have the eastern parts as far as the sea, for Dan, one portion."}}, {"v": 2, "ref": "48:2", "o": "וְ/עַ֣ל גְּב֣וּל דָּ֗ן מִ/פְּאַ֥ת קָדִ֛ים עַד פְּאַת יָ֖מָּ/ה אָשֵׁ֥ר אֶחָֽד", "en": {"kjv": "And by the border of Dan, from the east side unto the west side, a portion for Asher.", "web": "By the border of Dan, from the east side to the west side, Asher, one portion.", "bsb": "Asher will have one portion bordering the territory of Dan from east to west.", "asv": "And by the border of Dan, from the east side unto the west side, Asher, one portion.", "ylt": "and by the border of Dan, from the east side unto the west side, Asher one,", "dra": "And by the border of Dan, from the east side even to the side of the sea, one portion for Aser:", "bbe": "And on the limit of Dan, from the east side to the west side: Asher, one part.", "geneva": "And by the border of Dan from the East side vnto the West side, a portion for Asher.", "wycliffe": "And fro the ende of Dan, fro the eest coost til to the coost of the see, o part schal be of Aser.", "rotherham": "And, on the boundary of Dan from the east side unto the west side,—Asher one", "darby": "And by the border of Dan, from the east side unto the west side, Asher one.", "twenty": "", "jps": "And by the border of Dan, from the east side unto the west side: Asher, one portion.", "acv": "And by the border of Dan, from the east side to the west side, Asher, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Dan, from the east side to the west side: Asher, one tribe.", "webster": "And by the border of Dan, from the east side to the west side, a [portion for] Asher.", "vulgate": "et ad terminum Dan a plaga orientali usque ad plagam maris Aser una;", "brenton": "And from the borders of Dan eastward as far as the west sea-coast, for Asser, one."}}, {"v": 3, "ref": "48:3", "o": "וְ/עַ֣ל גְּב֣וּל אָשֵׁ֗ר מִ/פְּאַ֥ת קָדִ֛ימָ/ה וְ/עַד פְּאַת יָ֖מָּ/ה נַפְתָּלִ֥י אֶחָֽד", "en": {"kjv": "And by the border of Asher, from the east side even unto the west side, a portion for Naphtali.", "web": "By the border of Asher, from the east side even to the west side, Naphtali, one portion.", "bsb": "Naphtali will have one portion bordering the territory of Asher from east to west.", "asv": "And by the border of Asher, from the east side even unto the west side, Naphtali, one portion.", "ylt": "and by the border of Asher, from the east side even unto the west side, Naphtali one,", "dra": "And by the border of Aser, from the east side even to the side of the sea one portion for Nephthali.", "bbe": "And on the limit of Asher, from the east side to the west side: Naphtali, one part.", "geneva": "And by the border of Asher from the East parte euen vnto the West parte a portion for Naphtali.", "wycliffe": "And on the ende of Azer, fro the eest coost til to the coost of the see, oon of Neptalym.", "rotherham": "And, on the boundary of Asher from the east side even unto the west side,- Naphtali one.", "darby": "And by the border of Asher, from the east side even unto the west side, Naphtali one.", "twenty": "", "jps": "And by the border of Asher, from the east side even unto the west side: Naphtali, one portion.", "acv": "And by the border of Asher, from the east side even to the west side, Naphtali, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Asher, from the east side to the west side: Naphtali, one tribe.", "webster": "And by the border of Asher, from the east side even to the west side, a [portion for] Naphtali.", "vulgate": "et super terminum Aser a plaga orientali usque ad plagam maris Nepthalim una;", "brenton": "And from the borders of Asser, from the eastern parts as far as the west coasts, for Nephthalim, one."}}, {"v": 4, "ref": "48:4", "o": "וְ/עַ֣ל גְּב֣וּל נַפְתָּלִ֗י מִ/פְּאַ֥ת קָדִ֛מָ/ה עַד פְּאַת יָ֖מָּ/ה מְנַשֶּׁ֥ה אֶחָֽד", "en": {"kjv": "And by the border of Naphtali, from the east side unto the west side, a portion for Manasseh.", "web": "By the border of Naphtali, from the east side to the west side, Manasseh, one portion.", "bsb": "Manasseh will have one portion bordering the territory of Naphtali from east to west.", "asv": "And by the border of Naphtali, from the east side unto the west side, Manasseh, one portion.", "ylt": "and by the border of Naphtali, from the east side unto the west side, Manasseh one,", "dra": "And by the border of Nephthali, from the east side even to the side of the one portion for Manasses.", "bbe": "And on the limit of Naphtali, from the east side to the west side: Manasseh, one part.", "geneva": "And by the border of Naphtali from the East quarter vnto the West side, a portion for Manasseh.", "wycliffe": "And on the terme of Neptalym, fro the eest coost til to the coost of the see, oon of Manasses.", "rotherham": "And, on the boundary of Naphtali from the east side unto the west side,— Manasseh one.", "darby": "And by the border of Naphtali, from the east side unto the west side, Manasseh one.", "twenty": "", "jps": "And by the border of Naphtali, from the east side unto the west side: Manasseh, one portion.", "acv": "And by the border of Naphtali, from the east side to the west side, Manasseh, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Naphtali, from the east side to the west side: Manasseh, one tribe.", "webster": "And by the border of Naphtali, from the east side to the west side, a [portion for] Manasseh.", "vulgate": "et super terminum Nepthalim a plaga orientali usque ad plagam maris Manasse una;", "brenton": "And from the borders of Nephthalim, from the east as far as the west coasts, for Manasse, one."}}, {"v": 5, "ref": "48:5", "o": "וְ/עַ֣ל גְּב֣וּל מְנַשֶּׁ֗ה מִ/פְּאַ֥ת קָדִ֛מָ/ה עַד פְּאַת יָ֖מָּ/ה אֶפְרַ֥יִם אֶחָֽד", "en": {"kjv": "And by the border of Manasseh, from the east side unto the west side, a portion for Ephraim.", "web": "By the border of Manasseh, from the east side to the west side, Ephraim, one portion.", "bsb": "Ephraim will have one portion bordering the territory of Manasseh from east to west.", "asv": "And by the border of Manasseh, from the east side unto the west side, Ephraim, one portion.", "ylt": "and by the border of Manasseh, from the east side unto the west side, Ephraim one,", "dra": "And by the border of Manasses, from the east side even to the side of the sea, one portion for Ephraim.", "bbe": "And on the limit of Manasseh, from the east side to the west side: Ephraim, one part.", "geneva": "And by the border of Manasseh from the East side vnto the West side a portion for Ephraim.", "wycliffe": "And on the ende of Manasses, fro the eest coost til to the coost of the see, oon of Effraym.", "rotherham": "And, on the boundary of Manasseh from the east side unto the west side,— Ephraim, one.", "darby": "And by the border of Manasseh, from the east side unto the west side, Ephraim one.", "twenty": "", "jps": "And by the border of Manasseh, from the east side unto the west side: Ephraim, one portion.", "acv": "And by the border of Manasseh, from the east side to the west side, Ephraim, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Manasseh, from the east side to the west side: Ephraim, one tribe.", "webster": "And by the border of Manasseh, from the east side to the west side, a [portion for] Ephraim.", "vulgate": "et super terminum Manasse a plaga orientali usque ad plagam maris Ephraim una;", "brenton": "And from the borders of Manasse, from the eastern parts as far as the west coasts, for Ephraim, one."}}, {"v": 6, "ref": "48:6", "o": "וְ/עַ֣ל גְּב֣וּל אֶפְרַ֗יִם מִ/פְּאַ֥ת קָדִ֛ים וְ/עַד פְּאַת יָ֖מָּ/ה רְאוּבֵ֥ן אֶחָֽד", "en": {"kjv": "And by the border of Ephraim, from the east side even unto the west side, a portion for Reuben.", "web": "By the border of Ephraim, from the east side even to the west side, Reuben, one portion.", "bsb": "Reuben will have one portion bordering the territory of Ephraim from east to west.", "asv": "And by the border of Ephraim, from the east side even unto the west side, Reuben, one portion.", "ylt": "and by the border of Ephraim, from the east side even unto the west side, Reuben one,", "dra": "And by the border of Ephraim, from the east side even to the side of the sea, one portion for Ruben.", "bbe": "And on the limit of Ephraim, from the east side to the west side: Reuben, one part.", "geneva": "And by the border of Ephraim, from the East part euen vnto the West part, a portion for Reuben.", "wycliffe": "And on the ende of Effraym, fro the eest coost til to the coost of the see, oon of Ruben.", "rotherham": "And, on the boundary of Ephraim from the east side even unto the west side, Reuben one.", "darby": "And by the border of Ephraim, from the east side even unto the west side, Reuben one.", "twenty": "", "jps": "And by the border of Ephraim, from the east side even unto the west side: Reuben, one portion.", "acv": "And by the border of Ephraim, from the east side even to the west side, Reuben, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Ephraim, from the east side to the west side: Reuben, one tribe.", "webster": "And by the border of Ephraim, from the east side even to the west side, a [portion for] Reuben.", "vulgate": "et super terminum Ephraim a plaga orientali usque ad plagam maris Ruben una;", "brenton": "And from the borders of Ephraim, from the eastern parts to the west coasts, for Ruben, one."}}, {"v": 7, "ref": "48:7", "o": "וְ/עַ֣ל גְּב֣וּל רְאוּבֵ֗ן מִ/פְּאַ֥ת קָדִ֛ים עַד פְּאַת יָ֖מָּ/ה יְהוּדָ֥ה אֶחָֽד", "en": {"kjv": "And by the border of Reuben, from the east side unto the west side, a portion for Judah.", "web": "By the border of Reuben, from the east side to the west side, Judah, one portion.", "bsb": "Judah will have one portion bordering the territory of Reuben from east to west.", "asv": "And by the border of Reuben, from the east side unto the west side, Judah, one portion.", "ylt": "and by the border of Reuben, from the east side unto the west side, Judah one,", "dra": "And by the border of Ruben, from the east side even to the side of the sea, one portion for Juda.", "bbe": "And on the limit of Reuben, from the east side to the west side: Judah, one part.", "geneva": "And by the border of Reuben, from the East quarter vnto the West quarter, a portion for Iudah.", "wycliffe": "And on the ende of Ruben, fro the eest coost til to the coost of the see, oon of Juda.", "rotherham": "And, on the boundary of Reuben from the east side unto the west side,— Judah one.", "darby": "And by the border of Reuben, from the east side unto the west side, Judah one.", "twenty": "", "jps": "And by the border of Reuben, from the east side unto the west side: Judah, one portion.", "acv": "And by the border of Reuben, from the east side to the west side, Judah, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Reuben, from the east side to the west side: Judah, one tribe.", "webster": "And by the border of Reuben, from the east side to the west side, a [portion for] Judah.", "vulgate": "et super terminum Ruben a plaga orientali usque ad plagam maris Iuda una;", "brenton": "And from the borders of Ruben, from the eastern parts as far as the west coasts, for Juda, one."}}, {"v": 8, "ref": "48:8", "o": "וְ/עַל֙ גְּב֣וּל יְהוּדָ֔ה מִ/פְּאַ֥ת קָדִ֖ים עַד פְּאַת יָ֑מָּ/ה תִּהְיֶ֣ה הַ/תְּרוּמָ֣ה אֲֽשֶׁר תָּרִ֡ימוּ חֲמִשָּׁה֩ וְ/עֶשְׂרִ֨ים אֶ֜לֶף רֹ֗חַב וְ/אֹ֜רֶךְ כְּ/אַחַ֤ד הַ/חֲלָקִים֙ מִ/פְּאַ֤ת קָדִ֨ימָ/ה֙ עַד פְּאַת יָ֔מָּ/ה וְ/הָיָ֥ה הַ/מִּקְדָּ֖שׁ בְּ/תוֹכֽ/וֹ", "en": {"kjv": "And by the border of Judah, from the east side unto the west side, shall be the offering which ye shall offer of five and twenty thousand reeds in breadth, and in length as one of the other parts, from the east side unto the west side: and the sanctuary shall be in the midst of it.", "web": "By the border of Judah, from the east side to the west side, shall be the offering which you shall offer, twenty-five thousand reeds in breadth, and in length as one of the portions, from the east side to the west side: and the sanctuary shall be in its midst.", "bsb": "Bordering the territory of Judah, from east to west, will be the portion you are to set apart. It will be 25,000 cubits wide, and the length of a tribal portion from east to west. In the center will be the sanctuary.", "asv": "And by the border of Judah, from the east side unto the west side, shall be the oblation which ye shall offer, five and twenty thousand reeds in breadth, and in length as one of the portions, from the east side unto the west side: and the sanctuary shall be in the midst of it.", "ylt": "and by the border of Judah, from the east side unto the west side is the heave-offering that ye lift up, five and twenty thousand broad and long, as one of the parts, from the east side unto the west side: and the sanctuary hath been in its midst.", "dra": "And by the border of Juda, from the east side even to the side of the sea, shall be the firstfruits which you shall set apart, five and twenty thousand in breadth, and length, as every one of the portions from the east side to the side of the sea: and the sanctuary shall be in the midst thereof.", "bbe": "And on the limit of Judah, from the east side to the west side, will be the offering which you are to make, twenty-five thousand wide, and as long as one of the parts, from the east side to the west side: and the holy place will be in the middle of it.", "geneva": "And by the border of Iudah from the East part vnto the West part shall be the offering which they shall offer of fiue and twentie thousande reedes broade, and of length as one of the other parts, from the East side vnto the Westside, and the Sanctuarie shalbe in the middes of it.", "wycliffe": "And on the ende of Juda, fro the eest coost til to the coost of the see, schulen be the firste fruytis, whiche ye schulen departe bi fyue and twenti thousynde reheedis of breede and of lengthe, as alle partis ben, fro the eest coost til to the coost of the see; and the seyntuarie schal be in the myddis therof.", "rotherham": "And, on the boundary of Judah, from the east side unto the west side, shall be the heave-offering which ye shall offer up, five and twenty thousand in breadth and, in length, like one of the portions from the east side unto the west side, so shall the sanctuary be in the midst thereof.", "darby": "And by the border of Judah, from the east side unto the west side, shall be the heave-offering that ye shall offer, five and twenty thousand [cubits] in breadth, and in length as one of the parts from the east side unto the west side: and the sanctuary shall be in the midst of it.", "twenty": "", "jps": "And by the border of Judah, from the east side unto the west side, shall be the offering which ye shall set aside, five and twenty thousand reeds in breadth, and in length as one of the portions, from the east side unto the west side; and the sanctuary shall be in the midst of it.", "acv": "And by the border of Judah, from the east side to the west side, shall be the oblation which ye shall offer: twenty-five thousand measures in breadth, and in length as one of the portions, from the east side to the west side. And the sanctuary shall be in the midst of it.", "anderson": "", "haweis": "", "noyes": "And by the border of Judah, from the east side to the west, shall be the oblation which ye shall offer, five and twenty thousand reeds in breadth, and in length as one of the other portions from the east side to the west side; and the sanctuary shall be in the midst of it.", "webster": "And by the border of Judah, from the east side to the west side, shall be the offering which ye shall offer of five and twenty thousand [reeds in] breadth, and [in] length as one of the [other] parts, from the east side to the west side: and the sanctuary shall be in the midst of it.", "vulgate": "et super terminum Iuda a plaga orientali usque ad plagam maris erunt primitiae quas separabitis viginti quinque milibus latitudinis et longitudinis sicuti singulae partes a plaga orientali usque ad plagam maris et erit sanctuarium in medio eius;", "brenton": "And from the borders of Juda, from the eastern parts shall be the offering of first-fruits, in the breadth twenty-five thousand reeds, and in length as one of the portions measured from the east even to the western parts: and the sanctuary shall be in the midst of them."}}, {"v": 9, "ref": "48:9", "o": "הַ/תְּרוּמָ֕ה אֲשֶׁ֥ר תָּרִ֖ימוּ לַֽ/יהוָ֑ה אֹ֗רֶךְ חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף וְ/רֹ֖חַב עֲשֶׂ֥רֶת אֲלָפִֽים", "en": {"kjv": "The oblation that ye shall offer unto the Lord shall be of five and twenty thousand in length, and of ten thousand in breadth.", "web": "The offering that you shall offer to Yahweh shall be twenty-five thousand reeds in length, and ten thousand in breadth.", "bsb": "The special portion you set apart to the LORD shall be 25,000 cubits long and 10,000 cubits wide.", "asv": "The oblation that ye shall offer unto Jehovah shall be five and twenty thousand reeds in length, and ten thousand in breadth.", "ylt": "The heave-offering that ye lift up to Jehovah is five and twenty thousand long, and broad ten thousand.", "dra": "The firstfruits which you shall set apart for the Lord will be the length of five and twenty thousand, and the breadth of ten thousand.", "bbe": "The offering you will give to the Lord is to be twenty-five thousand long and twenty-five thousand wide.", "geneva": "The oblation that ye shall offer vnto the Lord, shalbe of fiue and twentie thousande long, and of ten thousand the breadth.", "wycliffe": "The firste fruytis whiche ye schulen departe to the Lord, the lengthe schal be in fyue and twenty thousynde, and the breed in ten thousynde.", "rotherham": "the heave-offering which ye shall offer up to Yahweh shall be in length, five and twenty thousand, and in breadth, twenty thousand.", "darby": "The heave-offering that ye shall offer unto Jehovah shall be five and twenty thousand in length, and ten thousand in breadth.", "twenty": "", "jps": "The offering that ye shall set apart unto HaShem shall be five and twenty thousand reeds in length, and ten thousand in breadth.", "acv": "The oblation that ye shall offer to Jehovah shall be twenty-five thousand measures in length, and ten thousand in breadth.", "anderson": "", "haweis": "", "noyes": "The oblation which ye shall offer to Jehovah shall be five and twenty thousand reeds in length, and ten thousand in breadth.", "webster": "The oblation that ye shall offer to the LORD [shall be] of five and twenty thousand in length, and of ten thousand in breadth.", "vulgate": "primitiae quas separastis Domino longitudo viginti quinque milibus et latitudo decem milibus;", "brenton": "As for the first-fruits which they shall offer to the Lord, it shall be in length twenty-five thousand, and in breadth twenty-five thousand."}}, {"v": 10, "ref": "48:10", "o": "וּ֠/לְ/אֵ֜לֶּה תִּהְיֶ֣ה תְרֽוּמַת הַ/קֹּדֶשׁ֮ לַ/כֹּֽהֲנִים֒ צָפ֜וֹנָ/ה חֲמִשָּׁ֧ה וְ/עֶשְׂרִ֣ים אֶ֗לֶף וְ/יָ֨מָּ/ה֙ רֹ֚חַב עֲשֶׂ֣רֶת אֲלָפִ֔ים וְ/קָדִ֗ימָ/ה רֹ֚חַב עֲשֶׂ֣רֶת אֲלָפִ֔ים וְ/נֶ֕גְבָּ/ה אֹ֕רֶךְ חֲמִשָּׁ֥ה וְ/עֶשְׂרִ֖ים אָ֑לֶף וְ/הָיָ֥ה מִקְדַּשׁ יְהוָ֖ה בְּ/תוֹכֽ/וֹ", "en": {"kjv": "And for them, even for the priests, shall be this holy oblation; toward the north five and twenty thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south five and twenty thousand in length: and the sanctuary of the Lord shall be in the midst thereof.", "web": "For these, even for the priests, shall be the holy offering: toward the north twenty-five thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south twenty-five thousand in length: and the sanctuary of Yahweh shall be in its midst.", "bsb": "This will be the holy portion for the priests. It will be 25,000 cubits long on the north side, 10,000 cubits wide on the west side, 10,000 cubits wide on the east side, and 25,000 cubits long on the south side. In the center will be the sanctuary of the LORD.", "asv": "And for these, even for the priests, shall be the holy oblation; toward the north five and twenty thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south five and twenty thousand in length: and the sanctuary of Jehovah shall be in the midst thereof.", "ylt": "And of these is the holy heave-offering for the priests, northward five and twenty thousand, and westward in breadth ten thousand, and eastward in breadth ten thousand, and southward in length five and twenty thousand: and the sanctuary of Jehovah hath been in its midst.", "dra": "And these shall be the firstfruits of the sanctuary for the priests: toward the north five and twenty thousand in length, and toward the sea ten thousand in breadth, and toward the east also ten thousand in breadth, and toward the south five and twenty thousand in length: and the sanctuary of the Lord shall be in the midst thereof.", "bbe": "And for these, that is the priests, the holy offering is to be twenty-five thousand long to the north, ten thousand wide to the west, ten thousand wide to the east and twenty-five thousand long to the south; and the holy place of the Lord will be in the middle of it.", "geneva": "And for them, euen for the Priestes shalbe this holy oblation, towarde the North fiue and twentie thousande long, and towarde the West, ten thousande broade, and towarde the East ten thousand broad, and towarde the South fiue and twentie thousand long, and the Sanctuarie of the Lord shalbe in the middes thereof.", "wycliffe": "Forsothe these schulen be the firste fruytis of the seyntuarie of preestis; to the north fyue and twenti thousynde of lengthe, and to the see ten thousinde of breede; but to the eest ten thousynde of breede, and to the south fyue and twenti thousynde of lengthe; and the seyntuarie of the Lord schal be in the myddis therof.", "rotherham": "And pertaining to these, shall he the holy offering, even for the priests, northwards, five and twenty thousand, and westward, a breadth of ten thousand, and eastward, a breadth of ten thousand and southward, a length of five and twenty thousand,—so shall the sanctuary of Yahweh be in the midst thereof:—", "darby": "And for them, for the priests, shall be the holy heave-offering, toward the north five and twenty thousand, and toward the west the breadth ten thousand, and toward the east the breadth ten thousand, and toward the south the length five and twenty thousand: and the sanctuary of Jehovah shall be in the midst of it.", "twenty": "", "jps": "And for these, even for the priests, shall be the holy offering; toward the north five and twenty thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south five and twenty thousand in length; and the sanctuary of HaShem shall be in the midst thereof.", "acv": "And for these, even for the priests, shall be the holy oblation: toward the north twenty-five thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south twenty-five thousand in length. And the sanctuary of Jehovah shall be in the midst of it.", "anderson": "", "haweis": "", "noyes": "And the holy oblation shall be for these: for the priests toward the north five and twenty thousand reeds in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south five and twenty thousand in length. And the sanctuary of Jehovah shall be in the midst thereof.", "webster": "And for them, [even] for the priests, shall be [this] holy oblation; towards the north five and twenty thousand [in length], and towards the west ten thousand in breadth, and towards the east ten thousand in breadth, and towards the south five and twenty thousand in length: and the sanctuary of the LORD shall be in the midst of it.", "vulgate": "hae autem erunt primitiae sanctuarii sacerdotum ad aquilonem viginti quinque milia et ad mare latitudinis decem milia sed et ad orientem latitudinis decem milia et ad meridiem longitudinis viginti quinque milia et erit sanctuarium Domini in medio eius;", "brenton": "Out of this shall be the first-fruits of the holy things to the priests, northward, five and twenty-thousand, and towards the west, ten thousand, and southward, five and twenty thousand: and the mountain of the sanctuary, shall be in the midst of it,"}}, {"v": 11, "ref": "48:11", "o": "לַ/כֹּהֲנִ֤ים הַֽ/מְקֻדָּשׁ֙ מִ/בְּנֵ֣י צָד֔וֹק אֲשֶׁ֥ר שָׁמְר֖וּ מִשְׁמַרְתִּ֑/י אֲשֶׁ֣ר לֹֽא תָע֗וּ בִּ/תְעוֹת֙ בְּנֵ֣י יִשְׂרָאֵ֔ל כַּ/אֲשֶׁ֥ר תָּע֖וּ הַ/לְוִיִּֽם", "en": {"kjv": "It shall be for the priests that are sanctified of the sons of Zadok; which have kept my charge, which went not astray when the children of Israel went astray, as the Levites went astray.", "web": "It shall be for the priests who are sanctified of the sons of Zadok, who have kept my instruction, who didn’t go astray when the children of Israel went astray, as the Levites went astray.", "bsb": "It will be for the consecrated priests, the descendants of Zadok, who kept My charge and did not go astray as the Levites did when the Israelites went astray.", "asv": "It shall be for the priests that are sanctified of the sons of Zadok, that have kept my charge, that went not astray when the children of Israel went astray, as the Levites went astray.", "ylt": "For the priests who are sanctified of the sons of Zadok, who have kept My charge, who erred not in the erring of the sons of Israel, as the Levites erred,", "dra": "The sanctuary shall be for the priests of the sons of Sadoc, who kept my ceremonies, and went not astray when the children of Israel went astray, as the Levites also went astray.", "bbe": "For the priests who have been made holy, those of the sons of Zadok who kept the orders I gave them, who did not go out of the right way when the children of Israel went from the way, as the Levites did,", "geneva": "It shalbe for the Priestes that are sanctified of the sonnes of Zadok, which haue kept my charge, which went not astray when the children of Israel went astray, as the Leuites went astray.", "wycliffe": "The seyntuarie schal be to prestis of the sones of Sadoch, that kepten my cerymonyes, and erriden not, whanne the sones of Israel erriden, as also dekenes erriden.", "rotherham": "for the priests that are hallowed—the sons of Zadok, who kept my charge,—who went not astray when the sons of Israel went astray, as, the Levites, went astray.", "darby": "[It shall be] for the priests that are hallowed of the sons of Zadok, who kept my charge and went not astray when the children of Israel went astray, as the Levites went astray.", "twenty": "", "jps": "The sanctified portion shall be for the priests of the sons of Zadok, that have kept My charge, that went not astray when the children of Israel went astray, as the Levites went astray.", "acv": "It shall be for the priests who are sanctified of the sons of Zadok, who have kept my charge, who did not go astray when the sons of Israel went astray, as the Levites went astray.", "anderson": "", "haweis": "", "noyes": "It shall belong to the priests, the sanctified ones, to the sons of Zadok, who kept my charge, who went not astray when the sons of Israel went astray, as the Levites went astray.", "webster": "[It shall be] for the priests that are sanctified of the sons of Zadok; who have kept my charge, who went not astray when the children of Israel went astray, as the Levites went astray.", "vulgate": "sacerdotibus sanctuarium erit de filiis Sadoc qui custodierunt caerimonias meas et non erraverunt cum errarent filii Israhel sicut erraverunt et Levitae;", "brenton": "for the priests, for the consecrated sons of Sadduc, who keep the charges of the house, who erred not in the error of the children of Israel, as the Levites erred."}}, {"v": 12, "ref": "48:12", "o": "וְ/הָיְתָ֨ה לָ/הֶ֧ם תְּרוּמִיָּ֛ה מִ/תְּרוּמַ֥ת הָ/אָ֖רֶץ קֹ֣דֶשׁ קָדָשִׁ֑ים אֶל גְּב֖וּל הַ/לְוִיִּֽם", "en": {"kjv": "And this oblation of the land that is offered shall be unto them a thing most holy by the border of the Levites.", "web": "It shall be to them an offering from the offering of the land, a thing most holy, by the border of the Levites.", "bsb": "It will be a special portion for them set apart from the land, a most holy portion adjacent to the territory of the Levites.", "asv": "And it shall be unto them an oblation from the oblation of the land, a thing most holy, by the border of the Levites.", "ylt": "even the heave-offering hath been to them, out of the heave-offering of the land, most holy, by the border of the Levites.", "dra": "And for them shall be the firstfruits of the firstfruits of the land holy of holies, by the border of the Levites,", "bbe": "Even for them will be the offering from the offering of the land, a thing most holy, on the limit of the land given to the Levites.", "geneva": "Therefore this oblation of the land that is offred, shalbe theirs, as a thing most holy by the border of the Leuites.", "wycliffe": "And the firste fruytis schulen be to hem of the firste fruytis of the lond, the hooli of hooli thingis, bi the terme of dekenes.", "rotherham": "So then they shall have an offering out of the offering of the land a holy of holies,—toward the boundary of the Levites;", "darby": "And this offering heaved from the heave-offering of the land shall be unto them a thing most holy, by the border of the Levites.", "twenty": "", "jps": "And it shall be unto them a portion set apart from the offering of the land, a thing most holy, by the border of the Levites.", "acv": "And it shall be to them an oblation from the oblation of the land, a thing most holy, by the border of the Levites.", "anderson": "", "haweis": "", "noyes": "And it shall belong to them as an oblation out of the oblation of the land, as most holy, by the border of the Levites.", "webster": "And [this] oblation of the land that is offered shall be to them a thing most holy, by the border of the Levites.", "vulgate": "et erunt eis primitiae de primitiis terrae sanctum sanctorum iuxta terminum Levitarum;", "brenton": "And the first-fruits shall be given to them out of the first-fruits of the land, even a most holy portion from the borders of the Levites."}}, {"v": 13, "ref": "48:13", "o": "וְ/הַ/לְוִיִּ֗ם לְ/עֻמַּת֙ גְּב֣וּל הַ/כֹּהֲנִ֔ים חֲמִשָּׁ֨ה וְ/עֶשְׂרִ֥ים אֶ֨לֶף֙ אֹ֔רֶךְ וְ/רֹ֖חַב עֲשֶׂ֣רֶת אֲלָפִ֑ים כָּל אֹ֗רֶךְ חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף וְ/רֹ֖חַב עֲשֶׂ֥רֶת אֲלָפִֽים", "en": {"kjv": "And over against the border of the priests the Levites shall have five and twenty thousand in length, and ten thousand in breadth: all the length shall be five and twenty thousand, and the breadth ten thousand.", "web": "Answerable to the border of the priests, the Levites shall have twenty-five thousand in length, and ten thousand in breadth: all the length shall be twenty-five thousand, and the breadth ten thousand.", "bsb": "Bordering the territory of the priests, the Levites shall have an area 25,000 cubits long and 10,000 cubits wide. The whole length will be 25,000 cubits, and the width 10,000 cubits.", "asv": "And answerable unto the border of the priests, the Levites shall have five and twenty thousand in length, and ten thousand in breadth: all the length shall be five and twenty thousand, and the breadth ten thousand.", "ylt": "`And to the Levites over-against the border of the priests are five and twenty thousand in length, and in breadth ten thousand, all the length is five and twenty thousand, and the breadth ten thousand.", "dra": "And the Levites in like manner shall have by the borders of the priests five and twenty thousand in length, and ten thousand in breadth. All the length shall be five and twenty thousand, and the breadth ten thousand.", "bbe": "And the Levites are to have a part of the land equal to the limit of the priests', twenty-five thousand long and ten thousand wide, all of it together to be twenty-five thousand long and twenty thousand wide.", "geneva": "And ouer against the border of the Priests the Leuites shall haue fiue and twentie thousande long, and ten thousande broade: all the length shalbe fiue and twentie thousand, and the breadth ten thousande.", "wycliffe": "But also to dekenes in lijk maner bi the coostis of preestis schulen be fyue and twenti thousynde of lengthe, and ten thousynde of breede; al the lengthe of fiue and twenti thousynde, and the breede of ten thousynde.", "rotherham": "the Levites boundary answering to the boundary of the priests, five and twenty thousand in length and in breadth, ten thousand,—all the length five and twenty thousand, and the breadth twenty thousand.", "darby": "And answering to the border of the priests, the Levites shall have five and twenty thousand in length, and ten thousand in breadth: the whole length shall be five and twenty thousand, and the breadth ten thousand.", "twenty": "", "jps": "And answerable unto the border of the priests, the Levites shall have five and twenty thousand in length, and ten thousand in breadth; all the length shall be five and twenty thousand, and the breadth ten thousand.", "acv": "And answerable to the border of the priests, the Levites shall have twenty-five thousand in length, and ten thousand in breadth. All the length shall be twenty-five thousand, and the breadth ten thousand.", "anderson": "", "haweis": "", "noyes": "And over against the border of the priests, the Levites shall have five and twenty thousand reeds in length and ten thousand in breadth; the whole length five and twenty thousand, and the breadth ten thousand.", "webster": "And over against the border of the priests the Levites [shall have] five and twenty thousand in length, and ten thousand in breadth: all the length [shall be] five and twenty thousand, and the breadth ten thousand.", "vulgate": "sed et Levitis similiter iuxta fines sacerdotum viginti quinque milia longitudinis et latitudinis decem milia omnis longitudo viginti et quinque milium et latitudo decem milium;", "brenton": "And the Levites shall have the part, next to the borders of the priests, in length twenty-five thousand, and in breadth ten thousand: the whole length shall be five and twenty thousand, and the breadth twenty thousand."}}, {"v": 14, "ref": "48:14", "o": "וְ/לֹא יִמְכְּר֣וּ מִמֶּ֗/נּוּ וְ/לֹ֥א יָמֵ֛ר וְ/לֹ֥א יעבור יַעֲבִ֖יר רֵאשִׁ֣ית הָ/אָ֑רֶץ כִּי קֹ֖דֶשׁ לַ/יהוָֽה", "en": {"kjv": "And they shall not sell of it, neither exchange, nor alienate the firstfruits of the land: for it is holy unto the Lord.", "web": "They shall sell none of it, nor exchange it, nor shall the first fruits of the land be alienated; for it is holy to Yahweh.", "bsb": "They must not sell or exchange any of it, and they must not transfer this best part of the land, for it is holy to the LORD.", "asv": "And they shall sell none of it, nor exchange it, nor shall the first-fruits of the land be alienated; for it is holy unto Jehovah.", "ylt": "And they do not sell of it, nor exchange, nor cause to pass away the first-fruit of the land: for it is holy to Jehovah.", "dra": "And they shall not sell thereof, nor exchange, neither shall the firstfruits of the land be alienated, because they are sanctified to the Lord.", "bbe": "And they are not to let any of it go for a price, or give it in exchange; and the part of the land given to the Lord is not to go into other hands: for it is holy to the Lord.", "geneva": "And they shall not sel of it, neither change it, nor abalienate the first fruites of the land: for it is holy vnto the Lord.", "wycliffe": "And thei schulen not sille therof, nether schulen chaunge; and the firste fruytis of the lond schulen not be translatid, for tho ben halewid to the Lord.", "rotherham": "And they shall not sell thereof, nor shall one exchange or alienate the first-fruits of the land,—for it is holy unto Yahweh.", "darby": "And they shall not sell of it, neither exchange, nor alienate the first-fruits of the land: for it is holy unto Jehovah.", "twenty": "", "jps": "And they shall not sell of it, nor exchange, nor alienate the first portion of the land; for it is holy unto HaShem.", "acv": "And they shall sell none of it, nor exchange it, nor shall the first-fruits of the land be alienated, for it is holy to Jehovah.", "anderson": "", "haweis": "", "noyes": "And they shall not sell of it; neither shall they exchange or transfer the first fruits of the land; for it is holy to Jehovah.", "webster": "And they shall not sell of it, neither exchange, nor alienate the first-fruits of the land: for [it is] holy to the LORD.", "vulgate": "et non venundabunt ex eo neque mutabunt nec transferentur primitiae terrae quia sanctificatae sunt Domino;", "brenton": "No part of it shall be sold, nor measured as for sale, neither shall the first-fruits of the land be taken away: for they are holy to the Lord."}}, {"v": 15, "ref": "48:15", "o": "וַ/חֲמֵ֨שֶׁת אֲלָפִ֜ים הַ/נּוֹתָ֣ר בָּ/רֹ֗חַב עַל פְּנֵ֨י חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף חֹֽל ה֣וּא לָ/עִ֔יר לְ/מוֹשָׁ֖ב וּ/לְ/מִגְרָ֑שׁ וְ/הָיְתָ֥ה הָ/עִ֖יר ב/תוכ/ה בְּ/תוֹכֽ/וֹ", "en": {"kjv": "And the five thousand, that are left in the breadth over against the five and twenty thousand, shall be a profane place for the city, for dwelling, and for suburbs: and the city shall be in the midst thereof.", "web": "The five thousand that are left in the breadth, in front of the twenty-five thousand, shall be for common use, for the city, for dwelling and for suburbs; and the city shall be in its midst.", "bsb": "The remaining area, 5,000 cubits wide and 25,000 cubits long, will be for common use by the city, for houses, and for pastureland. The city will be in the center of it", "asv": "And the five thousand that are left in the breadth, in front of the five and twenty thousand, shall be for common use, for the city, for dwelling and for suburbs; and the city shall be in the midst thereof.", "ylt": "And the five thousand that is left in the breadth, on the front of the five and twenty thousand, is common--for the city, for dwelling, and for suburb, and the city hath been in its midst.", "dra": "But the five thousand that remain in the breadth over against the five and twenty thousand, shall be a profane place for the city for dwelling, and for suburbs and the city shall be in the midst thereof.", "bbe": "And the other five thousand, measured from side to side, in front of the twenty-five thousand, is to be for common use, for the town, for living in and for a free space: and the town will be in the middle of it.", "geneva": "And the fiue thousand that are left in the breadth ouer against the fiue and twentie thousande, shall be a prophane place for the citie, for housing, and for suburbes, and the citie shalbe in the middes thereof.", "wycliffe": "Sotheli the fyue thousynde, that ben left ouer in breede, bi fyue and twenti thousynde, schulen be the vnhooli thingis, ether comyn thingis, of the citee, in to dwellyng place, and in to subarbis; and the citee schal be in the myddis therof.", "rotherham": "And the five thousand that are left in the breadth, facing the five and twenty thousand, common shall it be to the city, for dwelling and for open space,—and the city shall be in the midst thereof.", "darby": "And the five thousand that are left in the breadth over against the five and twenty thousand, shall be a common [place] for the city, for dwellings and for suburbs: and the city shall be in the midst of it.", "twenty": "", "jps": "And the five thousand that are left in the breadth, in front of the five and twenty thousand, shall be for common use, for the city, for dwelling and for open land; and the city shall be in the midst thereof.", "acv": "And the five thousand that are left in the breadth, in front of the twenty-five thousand, shall be for common use, for the city, for dwelling and for suburbs. And the city shall be in the midst of it.", "anderson": "", "haweis": "", "noyes": "And the five thousand which are left in breadth, over against the five and twenty thousand in length, shall be common land for the city, for habitation and for suburbs. And the city shall be in the midst of it.", "webster": "And the five thousand, that are left in the breadth over against the five and twenty thousand, shall be a profane [place] for the city, for dwelling, and for suburbs, and the city shall be in the midst of it.", "vulgate": "quinque milia autem quae supersunt in latitudine per viginti quinque milia profana erunt urbis in habitaculum et in suburbana et erit civitas in medio eius;", "brenton": "But concerning the five thousand that remain in the breadth in the five and twenty thousand, they shall be a suburb to the city for dwelling, and for a space before it: and the city shall be in the midst thereof."}}, {"v": 16, "ref": "48:16", "o": "וְ/אֵלֶּה֮ מִדּוֹתֶי/הָ֒ פְּאַ֣ת צָפ֗וֹן חֲמֵ֤שׁ מֵאוֹת֙ וְ/אַרְבַּ֣עַת אֲלָפִ֔ים וּ/פְאַת נֶ֕גֶב חֲמֵ֥שׁ חמש מֵא֖וֹת וְ/אַרְבַּ֣עַת אֲלָפִ֑ים וּ/מִ/פְּאַ֣ת קָדִ֗ים חֲמֵ֤שׁ מֵאוֹת֙ וְ/אַרְבַּ֣עַת אֲלָפִ֔ים וּ/פְאַת יָ֕מָּ/ה חֲמֵ֥שׁ מֵא֖וֹת וְ/אַרְבַּ֥עַת אֲלָפִֽים", "en": {"kjv": "And these shall be the measures thereof; the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "web": "These shall be its measures: the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "bsb": "and will have these measurements: 4,500 cubits on the north side, 4,500 cubits on the south side, 4,500 cubits on the east side, and 4,500 cubits on the west side.", "asv": "And these shall be the measures thereof: the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "ylt": "And these are its measures: the north side five hundred, and four thousand, and the south side five hundred, and four thousand, and on the east side five hundred, and four thousand, and the west side five hundred, and four thousand.", "dra": "And these are the measures thereof: on the north side four thousand and five hundred: and on the south side four thousand and five hundred: and on the east side four thousand and five hundred: and on the west side four thousand and five hundred.", "bbe": "And these will be its measures: the north side, four thousand five hundred, and the south side, four thousand five hundred, and on the east side, four thousand five hundred, and on the west side, four thousand five hundred.", "geneva": "And these shall be the measures thereof, the North part fiue hundreth and foure thousand, and the South parte fiue hundreth and foure thousande, and the East parte fiue hundreth and foure thousande, and the West parte fiue hundreth and foure thousande.", "wycliffe": "And these schulen be the mesuris therof; at the north coost, fyue hundrid and foure thousynde of rehedis, and at the south coost, fyue hundrid and foure thousynde, and at the eest coost, fyue hundrid and foure thousynde, and at the west coost, fyue hundrid and foure thousynde.", "rotherham": "These moreover shall be the measures thereof the north side, four thousand and five hundred, and the south side, four thousand and five hundred,—and the east side, four thousand and five hundred, and the west side, four thousand and five hundred.", "darby": "And these shall be the measures thereof: the north side four thousand and five hundred [cubits], and the south side four thousand and five hundred, and the east side four thousand and five hundred, and the west side four thousand and five hundred.", "twenty": "", "jps": "And these shall be the measures thereof: the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "acv": "And these shall be the measures of it: the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "anderson": "", "haweis": "", "noyes": "And this shall be the measure thereof: the north side four thousand and five hundred, and the south side four thousand and five hundred, and the east side four thousand and five hundred, and the west side four thousand and five hundred.", "webster": "And these [shall be] the measures of it; the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.", "vulgate": "et heae mensurae eius ad plagam septentrionalem quingenti et quattuor milia et ad plagam meridianam quingenti et quattuor milia et ad plagam orientalem quingenti et quattuor milia et ad plagam occidentalem quingenti et quattuor milia;", "brenton": "And these shall be its dimensions; from the northern side four thousand and five hundred, and from the southern side four thousand and five hundred, and from the eastern side four thousand and five hundred, and from the western side they shall measure four thousand five hundred."}}, {"v": 17, "ref": "48:17", "o": "וְ/הָיָ֣ה מִגְרָשׁ֮ לָ/עִיר֒ צָפ֨וֹנָ/ה֙ חֲמִשִּׁ֣ים וּ/מָאתַ֔יִם וְ/נֶ֖גְבָּ/ה חֲמִשִּׁ֣ים וּ/מָאתָ֑יִם וְ/קָדִ֨ימָ/ה֙ חֲמִשִּׁ֣ים וּ/מָאתַ֔יִם וְ/יָ֖מָּ/ה חֲמִשִּׁ֥ים וּ/מָאתָֽיִם", "en": {"kjv": "And the suburbs of the city shall be toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "web": "The city shall have suburbs: toward the north two hundred fifty, and toward the south two hundred fifty, and toward the east two hundred fifty, and toward the west two hundred fifty.", "bsb": "The pastureland of the city will extend 250 cubits to the north, 250 cubits to the south, 250 cubits to the east, and 250 cubits to the west.", "asv": "And the city shall have suburbs: toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "ylt": "And the suburb to the city hath been northward, fifty and two hundred, and southward, fifty and two hundred, and eastward, fifty and two hundred, and westward, fifty and two hundred.", "dra": "And the suburbs of the city shall be to the north two hundred and fifty, and the south two hundred and fifty, and to the east two hundred and fifty, and to the sea two hundred and fifty.", "bbe": "And the town will have a free space on the north of two hundred and fifty, on the south of two hundred and fifty, on the east of two hundred and fifty, and on the west of two hundred and fifty.", "geneva": "And the suburbes of the citie shall be toward the North two hundreth and fiftie, and towarde the South two hundreth and fiftie, and towarde the East two hundreth and fiftie, and towarde the West two hundreth and fiftie.", "wycliffe": "Forsothe the subarbis of the citee at the north schulen be twei hundrid and fifti, and at the southe twei hundrid and fifti, and at the eest twei hundrid and fifti, and at the see, that is, the west, twei hundrid and fifti.", "rotherham": "And the open space of the city shall be, northward, two hundred and fifty, and southward, two hundred and fifty, —and eastward, two hundred and fifty, and westward, two hundred and fifty,", "darby": "And the suburbs of the city shall be toward the north two hundred and fifty [cubits], and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "twenty": "", "jps": "And the city shall have open land: toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "acv": "And the city shall have suburbs: toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "anderson": "", "haweis": "", "noyes": "And the suburbs of the city shall be toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.", "webster": "And the suburbs of the city shall be towards the north two hundred and fifty, and towards the south two hundred and fifty, and towards the east two hundred and fifty, and towards the west two hundred and fifty.", "vulgate": "erunt autem suburbana civitatis ad aquilonem ducenti quinquaginta et in meridie ducenti quinquaginta et ad orientem ducenti quinquaginta et ad mare ducenti quinquaginta;", "brenton": "And there shall be a space to the city northward two hundred and fifty, and southward two hundred and fifty, and eastward two hundred and fifty, and westward two hundred and fifty."}}, {"v": 18, "ref": "48:18", "o": "וְ/הַ/נּוֹתָ֨ר בָּ/אֹ֜רֶךְ לְ/עֻמַּ֣ת תְּרוּמַ֣ת הַ/קֹּ֗דֶשׁ עֲשֶׂ֨רֶת אֲלָפִ֤ים קָדִ֨ימָ/ה֙ וַ/עֲשֶׂ֤רֶת אֲלָפִים֙ יָ֔מָּ/ה וְ/הָיָ֕ה לְ/עֻמַּ֖ת תְּרוּמַ֣ת הַ/קֹּ֑דֶשׁ וְ/הָיְתָ֤ה תבואת/ה תְבֽוּאָת/וֹ֙ לְ/לֶ֔חֶם לְ/עֹבְדֵ֖י הָ/עִֽיר", "en": {"kjv": "And the residue in length over against the oblation of the holy portion shall be ten thousand eastward, and ten thousand westward: and it shall be over against the oblation of the holy portion; and the increase thereof shall be for food unto them that serve the city.", "web": "The remainder in the length, answerable to the holy offering, shall be ten thousand eastward, and ten thousand westward; and it shall be answerable to the holy offering; and its increase shall be for food to those who labor in the city.", "bsb": "The remainder of the length bordering the holy portion and running adjacent to it will be 10,000 cubits on the east side and 10,000 cubits on the west side. Its produce will supply food for the workers of the city.", "asv": "And the residue in the length, answerable unto the holy oblation, shall be ten thousand eastward, and ten thousand westward; and it shall be answerable unto the holy oblation; and the increase thereof shall be for food unto them that labor in the city.", "ylt": "`And the residue in length over-against the heave-offering of the holy portion is ten thousand eastward, and ten thousand westward, and it hath been over-against the heave-offering of the holy portion , and its increase hath been for food to the servants of the city,", "dra": "And the residue in length by the firstfruits of the sanctuary, ten thousand toward the east, and ten thousand toward the west, shall be as the firstfruits of the sanctuary: and the fruit thereof shall be for bread to them that serve the city.", "bbe": "And the rest, in measure as long as the holy offering, will be ten thousand to the east and ten thousand to the west: and its produce will be for food for the workers of the town.", "geneva": "And the residue in length ouer against the oblation of the holy portion shalbe ten thousand Eastwarde, and ten thousand Westwarde: and it shalbe ouer against the oblation of the holy portion, and the encrease thereof shall be for foode vnto them that serue in the citie.", "wycliffe": "But that that is residue in lengthe, bi the firste fruytis of the seyntuarie, ten thousynde in to the eest, and ten thousynde in to the west, schulen be as the firste fruitis of the seyntuarie; and the fruitis schulen be in to looues to hem that seruen the citee.", "rotherham": "And the residue in length answering to the offering of the holy portion, shall be ten thousand on the east and ten thousand on the west, so shall it answer to the offering of the holy portion,- and the increase thereof shall be for food, for them who serve the city.", "darby": "And the residue in length, alongside the holy heave-offering, shall be ten thousand eastward and ten thousand westward: it shall be alongside the holy heave-offering; and the increase thereof shall be for the support of them that serve the city.", "twenty": "", "jps": "And the residue in the length, answerable unto the holy offering, shall be ten thousand eastward, and ten thousand westward; and it shall be answerable unto the holy offering; and the increase thereof shall be for food unto them that serve the city.", "acv": "And the residue in the length, answerable to the holy oblation, shall be ten thousand eastward, and ten thousand westward. And it shall be answerable to the holy oblation. And the increase of it shall be for food to those who labor in the city.", "anderson": "", "haweis": "", "noyes": "And as to the residue in length, over against the holy portion, ten thousand eastward and ten thousand westward, over against the holy portion, its increase shall be for food to them that serve the city.", "webster": "And the residue in length over against the oblation of the holy [portion shall be] ten thousand eastward, and ten thousand westward: and it shall be over against the oblation of the holy [portion]; and its increase shall be for food to them that serve the city.", "vulgate": "quod autem reliquum fuerit in longitudine secundum primitias sanctuarii decem milia in orientem et decem milia ad occidentem erunt sicut primitiae sanctuarii et erunt fruges eius in panes his qui serviunt civitati;", "brenton": "And the remainder of the length that is next to the first-fruits of the holy portion shall be ten thousand eastward, and ten thousand westward: and they shall be the first-fruits of the sanctuary; and the fruits thereof shall be for bread to them that labour for the city."}}, {"v": 19, "ref": "48:19", "o": "וְ/הָ/עֹבֵ֖ד הָ/עִ֑יר יַעַבְד֕וּ/הוּ מִ/כֹּ֖ל שִׁבְטֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And they that serve the city shall serve it out of all the tribes of Israel.", "web": "Those who labor in the city, out of all the tribes of Israel, shall cultivate it.", "bsb": "The workers of the city who cultivate it will come from all the tribes of Israel.", "asv": "And they that labor in the city, out of all the tribes of Israel, shall till it.", "ylt": "even to him who is serving the city, they serve it out of all the tribes of Israel.", "dra": "And they that serve the city, shall serve it out of all the tribes of Israel.", "bbe": "It will be farmed by workers of the town from all the tribes of Israel.", "geneva": "And they that serue in the citie, shalbe of all the tribes of Israel that shall serue therein.", "wycliffe": "Forsothe thei that seruen the citee schulen worche, of alle the lynagis of Israel.", "rotherham": "And they who serve the city shall serve it out of all the tribes of Israel.", "darby": "And they that serve the city shall serve it out of all the tribes of Israel.", "twenty": "", "jps": "And they that serve the city, out of all the tribes of Israel, shall till it.", "acv": "And those who labor in the city, out of all the tribes of Israel, shall till it.", "anderson": "", "haweis": "", "noyes": "And they that serve the city shall serve it out of all the tribes of Israel.", "webster": "And they that serve the city shall serve it out of all the tribes of Israel.", "vulgate": "servientes autem civitati operabuntur ex omnibus tribubus Israhel;", "brenton": "And they that labour for the city shall labour for it out of all the tribes of Israel."}}, {"v": 20, "ref": "48:20", "o": "כָּל הַ/תְּרוּמָ֗ה חֲמִשָּׁ֤ה וְ/עֶשְׂרִים֙ אֶ֔לֶף בַּ/חֲמִשָּׁ֥ה וְ/עֶשְׂרִ֖ים אָ֑לֶף רְבִיעִ֗ית תָּרִ֨ימוּ֙ אֶת תְּרוּמַ֣ת הַ/קֹּ֔דֶשׁ אֶל אֲחֻזַּ֖ת הָ/עִֽיר", "en": {"kjv": "All the oblation shall be five and twenty thousand by five and twenty thousand: ye shall offer the holy oblation foursquare, with the possession of the city.", "web": "All the offering shall be a square of twenty-five thousand by twenty-five thousand: you shall offer it as a holy offering, with the possession of the city.", "bsb": "The entire portion will be a square, 25,000 cubits by 25,000 cubits. You are to set apart the holy portion, along with the city property.", "asv": "All the oblation shall be five and twenty thousand by five and twenty thousand: ye shall offer the holy oblation foursquare, with the possession of the city.", "ylt": "All the heave-offering is five and twenty thousand by five and twenty thousand, square do ye lift up the heave-offering of the holy portion with the possession of the city.", "dra": "All the firstfruits, of five and twenty thousand, by five and twenty thousand foursquare, shall be set apart for the firstfruits of the sanctuary, and for the possession of the city.", "bbe": "The size of the offering all together is to be twenty-five thousand by twenty-five thousand: you are to make the holy offering a square, together with the property of the town.", "geneva": "All the oblation shalbe fiue and twentie thousand with fiue and twentie thousand: you shall offer this oblation foure square for the Sanctuarie, and for the possession of the citie.", "wycliffe": "Alle the firste fruitis of fyue and twenti thousynde, bi fyue and twenti thousynde in square, schulen be departid in to the firste fruytis of seyntuarie, and in to possessioun of the citee.", "rotherham": "All the offering shall be five and twenty thousand, by five and twenty thousand, —foursquare, shall ye offer up the offering of the holy portion, towards the possession of the city.", "darby": "The whole heave-offering shall be five and twenty thousand by five and twenty thousand; ye shall offer the holy heave-offering foursquare with the possession of the city.", "twenty": "", "jps": "All the offering shall be five and twenty thousand by five and twenty thousand; ye shall set apart the holy offering foursquare, with the possession of the city.", "acv": "All the oblation shall be twenty-five thousand by twenty-five thousand. Ye shall offer the holy oblation four-square, with the possession of the city.", "anderson": "", "haweis": "", "noyes": "All the oblation shall be five and twenty thousand reeds by five and twenty thousand; ye shall offer the holy oblation, four-square, together with the possession of the city.", "webster": "All the oblation [shall be] five and twenty thousand by five and twenty thousand: ye shall offer the holy oblation foursquare, with the possession of the city.", "vulgate": "omnes primitiae viginti quinque milium per viginti quinque milia in quadrum separabuntur in primitias sanctuarii et possessionem civitatis;", "brenton": "The whole offering shall be a square of twenty-five thousand by twenty-five thousand: ye shall separate again part of it, the first-fruits of the sanctuary, from the possession of the city."}}, {"v": 21, "ref": "48:21", "o": "וְ/הַ/נּוֹתָ֣ר לַ/נָּשִׂ֣יא מִ/זֶּ֣ה וּ/מִ/זֶּ֣ה לִ/תְרֽוּמַת הַ/קֹּ֣דֶשׁ וְ/לַ/אֲחֻזַּ֪ת הָ/עִ֟יר אֶל פְּנֵ֣י חֲמִשָּׁה֩ וְ/עֶשְׂרִ֨ים אֶ֥לֶף תְּרוּמָה֮ עַד גְּב֣וּל קָדִימָ/ה֒ וְ/יָ֗מָּ/ה עַל פְּ֠נֵי חֲמִשָּׁ֨ה וְ/עֶשְׂרִ֥ים אֶ֨לֶף֙ עַל גְּב֣וּל יָ֔מָּ/ה לְ/עֻמַּ֥ת חֲלָקִ֖ים לַ/נָּשִׂ֑יא וְ/הָֽיְתָה֙ תְּרוּמַ֣ת הַ/קֹּ֔דֶשׁ וּ/מִקְדַּ֥שׁ הַ/בַּ֖יִת ב/תוכ/ה בְּ/תוֹכֽ/וֹ", "en": {"kjv": "And the residue shall be for the prince, on the one side and on the other of the holy oblation, and of the possession of the city, over against the five and twenty thousand of the oblation toward the east border, and westward over against the five and twenty thousand toward the west border, over against the portions for the prince: and it shall be the holy oblation; and the sanctuary of the house shall be in the midst thereof.", "web": "The remainder shall be for the prince, on the one side and on the other of the holy offering and of the possession of the city; in front of the twenty-five thousand of the offering toward the east border, and westward in front of the twenty-five thousand toward the west border, answerable to the portions, it shall be for the prince: and the holy offering and the sanctuary of the house shall be in its midst.", "bsb": "The remaining area on both sides of the holy portion and of the property of the city will belong to the prince. He will own the land adjacent to the tribal portions, extending eastward from the 25,000 cubits of the holy district toward the eastern border, and westward from the 25,000 cubits to the western border. And in the center of them will be the holy portion and the sanctuary of the temple.", "asv": "And the residue shall be for the prince, on the one side and on the other of the holy oblation and of the possession of the city; in front of the five and twenty thousand of the oblation toward the east border, and westward in front of the five and twenty thousand toward the west border, answerable unto the portions, it shall be for the prince: and the holy oblation and the sanctuary of the house shall be in the midst thereof.", "ylt": "`And the residue is for the prince, on this side and on that side of the heave-offering of the holy portion , and of the possession of the city, on the front of the five and twenty thousand of the heave-offering unto the east border, and westward, on the front of the five and twenty thousand on the west border, over-against the portions of the prince; and the heave-offering of the holy portion , and the sanctuary of the house, hath been in its midst.", "dra": "And the residue shall be for the prince on every side of the firstfruits of the sanctuary, and of the possession of the city over against the five and twenty thousand of the firstfruits unto the east border: toward the sea also over against the five and twenty thousand, unto the border of the sea, shall likewise be the portion of the prince: and the firstfruits of the sanctuary, and the sanctuary of the temple shall be in the midst thereof.", "bbe": "And the rest is to be for the prince, on this side and on that side of the holy offering and of the property of the town, in front of the twenty-five thousand to the east, as far as the east limit, and to the west, in front of the twenty-five thousand, as far as the west limit, and of the same measure as those parts; it will be the property of the prince: and the holy offering and holy place of the house will be in the middle of it.", "geneva": "And the residue shalbe for the prince on the one side and on the other of the oblation of the Sanctuarie, and of the possession of the citie, ouer against the fiue and twentie thousand of the oblation toward the East border, and Westward ouer against the fiue and twentie thousande towarde the West border, ouer against shalbe for the portion of the prince: this shall be the holy oblation, and the house of the Sanctuarie shalbe in the middes thereof.", "wycliffe": "Forsothe that that is residue, schal be the princes part, on ech side of the firste fruitis of seyntuarie, and of the possessioun of the citee, euene ayens fyue and twenti thousynde of the firste fruytis, til to the eest ende; but also to the see euene ayens fyue and twenti thousynde, til to the ende of the see, schal be in lijk maner in the partis of the prince; and the firste fruytis of the seyntuarye, and the seyntuarie of the temple schulen be in the myddis of it.", "rotherham": "And the residue shall be for the prince, on this side and on that side of the holy offering and of the possession of the city, facing the five and twenty thousand of the offering, as far as the east boundary, and westward, facing the five and twenty thousand by the west boundary, answering to the portions for the prince,- thus shall it be the holy offering, with the sanctuary of the house in the midst thereof.", "darby": "And the rest shall be for the prince, on the one side and on the other of the holy heave-offering and of the possession of the city, in front of the five and twenty thousand of the heave-offering toward the east border, and westward in front of the five and twenty thousand toward the west border, answering to the [other] portions: it shall be for the prince; and the holy heave-offering and the sanctuary of the house shall be in the midst of it.", "twenty": "", "jps": "And the residue shall be for the prince, on the one side and on the other of the holy offering and of the possession of the city, in front of the five and twenty thousand of the offering toward the east border, and westward in front of the five and twenty thousand toward the west border, answerable unto the portions, it shall be for the prince; and the holy offering and the sanctuary of the house shall be in the midst thereof.", "acv": "And the residue shall be for the ruler, on the one side and on the other of the holy oblation and of the possession of the city, in front of the twenty-five thousand of the oblation toward the east border, and westward in front of the twenty-five thousand toward the west border, answerable to the portions. It shall be for the ruler. And the holy oblation and the sanctuary of the house shall be in the midst of it.", "anderson": "", "haweis": "", "noyes": "And the residue on both sides of the holy oblation and of the possession of the city, over against the five and twenty thousand to the east border, and westward over against the five and twenty thousand to the west border, by the portions of the tribes, shall be for the prince; and the holy oblation and the sanctuary of the house shall be in the midst thereof.", "webster": "And the residue [shall be] for the prince, on the one side and on the other of the holy oblation, and of the possession of the city, over against the five and twenty thousand of the oblation towards the east border, and westward over against the five and twenty thousand towards the west border, over against the portions for the prince: and it shall be the holy oblation; and the sanctuary of the house [shall be] in the midst of it.", "vulgate": "quod autem reliquum fuerit principis erit ex omni parte primitiarum sanctuarii et possessionis civitatis e regione viginti quinque milium primitiarum usque ad terminum orientalem sed et ad mare e regione viginti quinque milium usque ad terminum maris similiter in partibus principis erit et erunt primitiae sanctuarii et sanctuarium templi in medio eius;", "brenton": "And the prince shall have the remainder on this side and on that side from the first-fruits of the sanctuary, and there shall be a possession of the city, for five and twenty thousand cubits in length, to the eastern and western borders, for five and twenty thousand to the western borders, next to the portions of the prince; and the first-fruits of the holy things and the sanctuary of the house shall be in the midst of it."}}, {"v": 22, "ref": "48:22", "o": "וּ/מֵ/אֲחֻזַּ֤ת הַ/לְוִיִּם֙ וּ/מֵ/אֲחֻזַּ֣ת הָ/עִ֔יר בְּ/ת֛וֹךְ אֲשֶׁ֥ר לַ/נָּשִׂ֖יא יִֽהְיֶ֑ה בֵּ֣ין גְּב֣וּל יְהוּדָ֗ה וּ/בֵין֙ גְּב֣וּל בִּנְיָמִ֔ן לַ/נָּשִׂ֖יא יִהְיֶֽה", "en": {"kjv": "Moreover from the possession of the Levites, and from the possession of the city, being in the midst of that which is the prince’s, between the border of Judah and the border of Benjamin, shall be for the prince.", "web": "Moreover from the possession of the Levites, and from the possession of the city, being in the midst of that which is the prince’s, between the border of Judah and the border of Benjamin, it shall be for the prince.", "bsb": "So the Levitical property and the city property will lie in the center of the area belonging to the prince—the area between the borders of Judah and Benjamin.", "asv": "Moreover from the possession of the Levites, and from the possession of the city, being in the midst of that which is the prince’s, between the border of Judah and the border of Benjamin, it shall be for the prince.", "ylt": "And from the possession of the Levites, from the possession of the city, in the midst of that which is to the prince, between the border of Judah and the border of Benjamin, there is to the prince.", "dra": "And from the possession of the Levites, and from the possession of the city which are in the midst of the prince's portions: what shall be to the border of Juda, and to the border of Benjamin, shall also belong to the prince.", "bbe": "And the property of the Levites and the property of the town will be in the middle of the prince's property; between the limit of Judah's part and the limit of Benjamin's part will be for the prince.", "geneva": "Moreouer, from the possession of the Leuites, and from the possession of the citie, that which is in the middes shall be the princes: betweene the border of Iudah, and betweene the border of Beniamin shall be the princes.", "wycliffe": "Forsothe fro the possessioun of dekenes, and fro the possessioun of the citee, which is in the myddis of partis of the prince, schal be in to the porcioun of Juda, and in to the porcioun of Beniamyn; and it schal perteyne to the prince.", "rotherham": "And out of the possession of the Levites and out of the possession of the city, in the midst of that which is for the prince, shall it be: between the boundary of Judah, and the boundary of Benjamin, for the prince shall it be.", "darby": "And from the possession of the Levites and from the possession of the city, being in the midst of that which shall be the prince's, between the border of Judah and the border of Benjamin, shall be for the prince.", "twenty": "", "jps": "Thus the possession of the Levites, and the possession of the city, shall be in the midst of that which is the prince's; between the border of Judah and the border of Benjamin shall be the prince's.", "acv": "Moreover from the possession of the Levites, and from the possession of the city, being in the midst of that which is the ruler's, between the border of Judah and the border of Benjamin, it shall be for the ruler.", "anderson": "", "haweis": "", "noyes": "What is left from the possession of the Levites and of the city, which are between what belongs to the prince, between the borders of Judah and Benjamin, shall belong to the prince.", "webster": "Moreover from the possession of the Levites, and from the possession of the city, [being] in the midst [of that] which is the prince's, between the border of Judah and the border of Benjamin, shall be for the prince.", "vulgate": "de possessione autem Levitarum et de possessione civitatis in medio partium principis erit inter terminum Iuda et inter terminum Beniamin et ad principem pertinebit;", "brenton": "And there shall be a portion taken from the Levites, from the possession of the city in the midst of the princes between the borders of Juda and the borders of Benjamin, and it shall be the portion of the princes."}}, {"v": 23, "ref": "48:23", "o": "וְ/יֶ֖תֶר הַ/שְּׁבָטִ֑ים מִ/פְּאַ֥ת קָדִ֛ימָ/ה עַד פְּאַת יָ֖מָּ/ה בִּנְיָמִ֥ן אֶחָֽד", "en": {"kjv": "As for the rest of the tribes, from the east side unto the west side, Benjamin shall have a portion.", "web": "As for the rest of the tribes: from the east side to the west side, Benjamin, one portion.", "bsb": "As for the rest of the tribes: Benjamin will have one portion extending from the east side to the west side.", "asv": "And as for the rest of the tribes: from the east side unto the west side, Benjamin, one portion.", "ylt": "`As to the rest of the tribes, from the east side unto the west side, Benjamin one,", "dra": "And for the rest of the tribes: from the east side to the west side, one portion for Benjamin.", "bbe": "And as for the rest of the tribes: from the east side to the west side: Benjamin, one part.", "geneva": "And the rest of the tribes shalbe thus: from the East parte vnto the West parte Beniamin shalbe a portion.", "wycliffe": "And to other lynagis, fro the eest coost `til to the west coost, oon to Beniamyn.", "rotherham": "And the residue of the tribes,—from the east side unto the west side, Benjamin one.", "darby": "And as for the rest of the tribes: from the east side unto the west side, Benjamin one [portion].", "twenty": "", "jps": "And as for the rest of the tribes: from the east side unto the west side: Benjamin, one portion.", "acv": "And as for the rest of the tribes, from the east side to the west side, Benjamin, one portion.", "anderson": "", "haweis": "", "noyes": "And as for the rest of the tribes, from the east side to the west side: Benjamin, one tribe.", "webster": "As for the rest of the tribes, from the east side to the west side, Benjamin [shall have] a [portion].", "vulgate": "et reliquis tribubus a plaga orientali usque ad plagam occidentalem Beniamin una;", "brenton": "And as for the rest of the tribes, from the eastern parts as far as the western, Benjamin shall have one portion."}}, {"v": 24, "ref": "48:24", "o": "וְ/עַ֣ל גְּב֣וּל בִּנְיָמִ֗ן מִ/פְּאַ֥ת קָדִ֛ימָ/ה עַד פְּאַת יָ֖מָּ/ה שִׁמְע֥וֹן אֶחָֽד", "en": {"kjv": "And by the border of Benjamin, from the east side unto the west side, Simeon shall have a portion.", "web": "By the border of Benjamin, from the east side to the west side, Simeon, one portion.", "bsb": "Simeon will have one portion bordering the territory of Benjamin from east to west.", "asv": "And by the border of Benjamin, from the east side unto the west side, Simeon, one portion.", "ylt": "and by the border of Benjamin, from the east side unto the west side, Simeon one,", "dra": "And over against the border of Benjamin, from the east side to the west side, one portion for Simeon.", "bbe": "And on the limit of Benjamin, from the east side to the west side: Simeon, one part.", "geneva": "And by the border of Beniamin, from the East side vnto the West side Simeon a portion.", "wycliffe": "And ayens the porcioun of Beniamyn, fro the eest coost til to the west coost, oon to Symeon.", "rotherham": "And on the boundary of Benjamin from the east side unto the west side, Simeon one.", "darby": "And by the border of Benjamin, from the east side unto the west side, Simeon one.", "twenty": "", "jps": "And by the border of Benjamin, from the east side unto the west side: Simeon, one portion.", "acv": "And by the border of Benjamin, from the east side to the west side, Simeon, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Benjamin, from the east side to the west side: Simeon, one tribe.", "webster": "And by the border of Benjamin, from the east side to the west side, Simeon [shall have] a [portion].", "vulgate": "et contra terminum Beniamin a plaga orientali usque ad plagam occidentalem Symeon una;", "brenton": "And from the borders of Benjamin, from the eastern parts to the western, Symeon, one."}}, {"v": 25, "ref": "48:25", "o": "וְ/עַ֣ל גְּב֣וּל שִׁמְע֗וֹן מִ/פְּאַ֥ת קָדִ֛ימָ/ה עַד פְּאַת יָ֖מָּ/ה יִשָׂשכָ֥ר אֶחָֽד", "en": {"kjv": "And by the border of Simeon, from the east side unto the west side, Issachar a portion.", "web": "By the border of Simeon, from the east side to the west side, Issachar, one portion.", "bsb": "Issachar will have one portion bordering the territory of Simeon from east to west.", "asv": "And by the border of Simeon, from the east side unto the west side, Issachar, one portion.", "ylt": "and by the border of Simeon, from the east side unto the west side, Issachar one,", "dra": "And by the border of Simeon, from the east side to the west side, one portion for Issachar.", "bbe": "And on the limit of Simeon, from the east side to the west side: Issachar, one part.", "geneva": "And by the border of Simeon from the East part vnto the West part, Isshachar a portion.", "wycliffe": "And on the terme of Symeon, fro the eest coost til to the west coost, oon to Isacar.", "rotherham": "And on the boundary of Simeon from the east side unto the west side, Issachar one.", "darby": "And by the border of Simeon, from the east side unto the west side, Issachar one.", "twenty": "", "jps": "And by the border of Simeon, from the east side unto the west side: Issachar, one portion.", "acv": "And by the border of Simeon, from the east side to the west side, Issachar, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Simeon, from the east side to the west side: Issachar, one tribe.", "webster": "And by the border of Simeon, from the east side to the west side, Issachar a [portion].", "vulgate": "et super terminum Symeonis a plaga orientali usque ad plagam occidentis Isachar una;", "brenton": "And from the borders of Symeon, from the eastern parts to the western, Issachar, one."}}, {"v": 26, "ref": "48:26", "o": "וְ/עַ֣ל גְּב֣וּל יִשָׂשכָ֗ר מִ/פְּאַ֥ת קָדִ֛ימָ/ה עַד פְּאַת יָ֖מָּ/ה זְבוּלֻ֥ן אֶחָֽד", "en": {"kjv": "And by the border of Issachar, from the east side unto the west side, Zebulun a portion.", "web": "By the border of Issachar, from the east side to the west side, Zebulun, one portion.", "bsb": "Zebulun will have one portion bordering the territory of Issachar from east to west.", "asv": "And by the border of Issachar, from the east side unto the west side, Zebulun, one portion.", "ylt": "and by the border of Issachar, from the east side unto the west side, Zebulun one,", "dra": "And by the border of Issachar, from the east side to the west side, one portion for Zabulon.", "bbe": "And on the limit of Issachar, from the east side to the west side: Zebulun, one part.", "geneva": "And by the border of Isshachar, from the East side vnto the West, Zebulun a portion.", "wycliffe": "And on the terme of Isacar, fro the eest coost til to the west coost, oon to Zabulon.", "rotherham": "And on the boundary of Issachar. from the east side unto the west side, Zebulun, one.", "darby": "And by the border of Issachar, from the east side unto the west side, Zebulun one.", "twenty": "", "jps": "And by the border of Issachar, from the east side unto the west side: Zebulun, one portion.", "acv": "And by the border of Issachar, from the east side to the west side, Zebulun, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Issachar, from the east side to the west side: Zebulon, one tribe.", "webster": "And by the border of Issachar, from the east side to the west side, Zebulun a [portion].", "vulgate": "et super terminum Isachar a plaga orientali usque ad plagam occidentalem Zabulon una;", "brenton": "And from the borders of Issachar, from the eastern parts to the western, Zabulon, one."}}, {"v": 27, "ref": "48:27", "o": "וְ/עַ֣ל גְּב֣וּל זְבוּלֻ֗ן מִ/פְּאַ֥ת קָדִ֛מָ/ה עַד פְּאַת יָ֖מָּ/ה גָּ֥ד אֶחָֽד", "en": {"kjv": "And by the border of Zebulun, from the east side unto the west side, Gad a portion.", "web": "By the border of Zebulun, from the east side to the west side, Gad, one portion.", "bsb": "And Gad will have one portion bordering the territory of Zebulun from east to west.", "asv": "And by the border of Zebulun, from the east side unto the west side, Gad, one portion.", "ylt": "and by the border of Zebulun, from the east side unto the west side, Gad one,", "dra": "And by the border of Zabulon, from the east side to the side of the sea, one portion for Gad.", "bbe": "And on the limit of Zebulun, from the east side to the west side: Gad one part.", "geneva": "And by the border of Zebulun from the East parte vnto the West part, Gad a portion.", "wycliffe": "And on the terme of Zabulon, fro the eest coost til to the coost of the see, oon to Gad.", "rotherham": "And on the boundary of Zebulun from the east side unto the west side, Gad, one.", "darby": "And by the border of Zebulun, from the east side unto the west side, Gad one.", "twenty": "", "jps": "And by the border of Zebulun, from the east side unto the west side: Gad, one portion.", "acv": "And by the border of Zebulun, from the east side to the west side, Gad, one portion.", "anderson": "", "haweis": "", "noyes": "And by the border of Zebulon, from the east side to the west side: Gad, one tribe.", "webster": "And by the border of Zebulun, from the east side to the west side, Gad a [portion].", "vulgate": "et super terminum Zabulon a plaga orientali usque ad plagam maris Gad una;", "brenton": "And from the borders of Zabulon, from the east to the western parts, Gad, one."}}, {"v": 28, "ref": "48:28", "o": "וְ/עַל֙ גְּב֣וּל גָּ֔ד אֶל פְּאַ֖ת נֶ֣גֶב תֵּימָ֑נָ/ה וְ/הָיָ֨ה גְב֜וּל מִ/תָּמָ֗ר מֵ֚י מְרִיבַ֣ת קָדֵ֔שׁ נַחֲלָ֖ה עַל הַ/יָּ֥ם הַ/גָּדֽוֹל", "en": {"kjv": "And by the border of Gad, at the south side southward, the border shall be even from Tamar unto the waters of strife in Kadesh, and to the river toward the great sea.", "web": "By the border of Gad, at the south side southward, the border shall be even from Tamar to the waters of Meribath Kadesh, to the brook, to the great sea.", "bsb": "The southern border of Gad will run from Tamar to the waters of Meribath-kadesh, then along the Brook of Egypt and out to the Great Sea.", "asv": "And by the border of Gad, at the south side southward, the border shall be even from Tamar unto the waters of Meribath-kadesh, to the brook of Egypt, unto the great sea.", "ylt": "and by the border of Gad, at the south side southward, the border hath been from Tamar to the waters of Meriboth-Kadesh, the stream by the great sea.", "dra": "And by the border of Gad, the south side southward: and the border shall be from Thamar, even to the waters of contradiction of Cades, the inheritance over against the great sea.", "bbe": "And on the limit of Gad, on the south side and to the south of it, the limit will be from Tamar to the waters of Meribath-kadesh, to the stream, to the Great Sea.", "geneva": "And by the border of Gad at the South side, towarde Temath, the border shall be euen from Tamar vnto the waters of Meribath in Kadesh, and to the riuer, that runneth into the maine sea.", "wycliffe": "And on the terme of Gad, to the coost of the south in to myddai; and the ende schal be fro Thamar til to the watris of ayenseying of Cades, and the eritage ayens the grete see.", "rotherham": "And on the boundary of Gad, by the south side southward,- so shall there be a boundary from Tamar [unto] the waters of Meribath-kadish, towards the torrent-bed, as far as the great sea.", "darby": "And by the border of Gad, at the south side southward, the border shall be from Tamar [to] the waters of Meribah-Kadesh, by the torrent, unto the great sea.", "twenty": "", "jps": "And by the border of Gad, at the south side southward, the border shall be even from Tamar unto the waters of Meribath-kadesh, to the Brook, unto the Great Sea.", "acv": "And by the border of Gad, at the south side southward, the border shall be even from Tamar to the waters of Meribath-kadesh, to the brook of Egypt, to the great sea.", "anderson": "", "haweis": "", "noyes": "And by the border of Gad, at the south side southward, shall the border be from Tamar to the waters of strife in Kadesh, even to the river by the great sea.", "webster": "And by the border of Gad, at the south side southward, the border shall be even from Tamar [to] the waters of strife [in] Kadesh, [and] to the river towards the great sea.", "vulgate": "et super terminum Gad ad plagam austri in meridiem et erit finis de Thamar usque ad aquas Contradictionis Cades hereditas contra mare magnum;", "brenton": "And from the borders of Gad, from the eastern parts to the south-western parts; his coasts shall even be from Thaeman, and the water of Barimoth Cades, for an inheritance, unto the great sea."}}, {"v": 29, "ref": "48:29", "o": "זֹ֥את הָ/אָ֛רֶץ אֲשֶׁר תַּפִּ֥ילוּ מִֽ/נַּחֲלָ֖ה לְ/שִׁבְטֵ֣י יִשְׂרָאֵ֑ל וְ/אֵ֨לֶּה֙ מַחְלְקוֹתָ֔/ם נְאֻ֖ם אֲדֹנָ֥/י יְהוִֽה", "en": {"kjv": "This is the land which ye shall divide by lot unto the tribes of Israel for inheritance, and these are their portions, saith the Lord God.", "web": "This is the land which you shall divide by lot to the tribes of Israel for inheritance, and these are their several portions, says the Lord Yahweh.", "bsb": "This is the land you are to allot as an inheritance to the tribes of Israel, and these will be their portions,” declares the Lord GOD.", "asv": "This is the land which ye shall divide by lot unto the tribes of Israel for inheritance, and these are their several portions, saith the Lord Jehovah.", "ylt": "This is the land that ye separate by inheritance to the tribes of Israel, and these are their portions--an affirmation of the Lord Jehovah.", "dra": "This is the land which you shall divide by lot to the tribes of Israel: and these are the portions of them, saith the Lord God.", "bbe": "This is the land of which distribution is to be made by the decision of the Lord, among the tribes of Israel for their heritage, and these are their heritages, says the Lord.", "geneva": "This is the lande, which ye shall distribute vnto the tribes of Israel for inheritance, and these are their portions, saith the Lord God.", "wycliffe": "This is the lond which ye schulen sende in to part to the lynagis of Israel, and these ben the partyngis of tho, seith the Lord God.", "rotherham": "This is the land which ye shall divide by lot for inheritance to the tribes of Israel,—and these shall be their portions, Declareth My Lord Yahweh,", "darby": "This is the land which ye shall divide by lot unto the tribes of Israel for inheritance, and these are their portions, saith the Lord Jehovah.", "twenty": "", "jps": "This is the land which ye shall divide by lot unto the tribes of Israel for inheritance, and these are their portions, saith the L-rd GOD.", "acv": "This is the land which ye shall divide by lot to the tribes of Israel for inheritance, and these are their several portions, says the lord Jehovah.", "anderson": "", "haweis": "", "noyes": "This is the land which ye shall divide by lot of the possession among the tribes of Israel, and these are their portions, saith the Lord Jehovah.", "webster": "This [is] the land which ye shall divide by lot to the tribes of Israel for inheritance, and these [are] their portions, saith the Lord GOD.", "vulgate": "haec est terra quam mittetis in sortem tribubus Israhel et hae partitiones earum ait Dominus Deus;", "brenton": "This is the land, which ye shall divide by lot to the tribes of Israel, and these are their portions, saith the Lord God."}}, {"v": 30, "ref": "48:30", "o": "וְ/אֵ֖לֶּה תּוֹצְאֹ֣ת הָ/עִ֑יר מִ/פְּאַ֣ת צָפ֔וֹן חֲמֵ֥שׁ מֵא֛וֹת וְ/אַרְבַּ֥עַת אֲלָפִ֖ים מִדָּֽה", "en": {"kjv": "And these are the goings out of the city on the north side, four thousand and five hundred measures.", "web": "These are the exits of the city: On the north side four thousand and five hundred reeds by measure;", "bsb": "“These will be the exits of the city:", "asv": "And these are the egresses of the city: On the north side four thousand and five hundred reeds by measure;", "ylt": "`And these are the outgoings of the city on the north side, five hundred, and four thousand measures.", "dra": "And these are the goings out of the city: on the north side thou shalt measure four thousand and five hundred.", "bbe": "And these are the outskirts of the town: on the north side, four thousand five hundred by measure;", "geneva": "And these are the boundes of the citie, on the North side fiue hundreth, and foure thousande measures.", "wycliffe": "And these ben the goyngis out of the citee; fro the north coost thou schalt mete fyue hundrid and foure thousynde rehedis.", "rotherham": "And these are the exits of the city,—on the north side, four thousand five hundred measures,", "darby": "And these are the goings out of the city. On the north side, four thousand and five hundred [cubits] by measure.", "twenty": "", "jps": "And these are the goings out of the city: on the north side four thousand and five hundred reeds by measure;", "acv": "And these are the exits of the city: On the north side four thousand and five hundred measures by measure.", "anderson": "", "haweis": "", "noyes": "And these are the gates of the city. On the north side shall the measure be four thousand five hundred reeds.", "webster": "And these [are] the goings out of the city on the north side, four thousand and five hundred measures.", "vulgate": "et hii egressus civitatis a plaga septentrionali quingentos et quattuor milia mensurabis;", "brenton": "And these are the goings out of the city northward, four thousand and five hundred by measure."}}, {"v": 31, "ref": "48:31", "o": "וְ/שַׁעֲרֵ֣י הָ/עִ֗יר עַל שְׁמוֹת֙ שִׁבְטֵ֣י יִשְׂרָאֵ֔ל שְׁעָרִ֥ים שְׁלוֹשָׁ֖ה צָפ֑וֹנָ/ה שַׁ֣עַר רְאוּבֵ֞ן אֶחָ֗ד שַׁ֤עַר יְהוּדָה֙ אֶחָ֔ד שַׁ֥עַר לֵוִ֖י אֶחָֽד", "en": {"kjv": "And the gates of the city shall be after the names of the tribes of Israel: three gates northward; one gate of Reuben, one gate of Judah, one gate of Levi.", "web": "and the gates of the city shall be after the names of the tribes of Israel, three gates northward: the gate of Reuben, one; the gate of Judah, one; the gate of Levi, one.", "bsb": "Beginning on the north side, which will be 4,500 cubits long, the gates of the city will be named after the tribes of Israel. On the north side there will be three gates: the gate of Reuben, the gate of Judah, and the gate of Levi.", "asv": "and the gates of the city shall be after the names of the tribes of Israel, three gates northward: the gate of Reuben, one; the gate of Judah, one; the gate of Levi, one.", "ylt": "And the gates of the city are according to the names of the tribes of Israel; three gates northward: the gate of Reuben one, the gate of Judah one, the gate of Levi one.", "dra": "And the gates of the city according to the names of the tribes of Israel, three gates on the north side, the gate of Ruben one, the gate of Juda one, the gate of Levi one.", "bbe": "And the doors of the town are to be named by the names of the tribes of Israel; three doors on the north, one for Reuben, one for Judah, one for Levi;", "geneva": "And the gates of the citie shalbe after the names of the tribes of Israel, the gates Northwarde, one gate of Reuben, one gate of Iudah, and one gate of Leui.", "wycliffe": "And yatis of the citee schulen be in alle the lynagis of Israel, thre yatis at the north; o yate of Ruben, o yate of Juda, o yate of Leuy.", "rotherham": "And the gates of the city, shall be after the names of the tribes of Israel; three gates, northward,-the gate of Reuben, one the gate of Judah, one the gate of Levi one;", "darby": "And the gates of the city shall be after the names of the tribes of Israel: three gates northward: the gate of Reuben, one; the gate of Judah, one; the gate of Levi, one.", "twenty": "", "jps": "and the gates of the city shall be after the names of the tribes of Israel; three gates northward: the gate of Reuben, one; the gate of Judah, one; the gate of Levi, one;", "acv": "And the gates of the city shall be according to the names of the tribes of Israel, three gates northward: the gate of Reuben, one, the gate of Judah, one, the gate of Levi, one.", "anderson": "", "haweis": "", "noyes": "And the gates of the city shall be after the names of the tribes of Israel; three gates northward,—one gate of Reuben, one gate of Judah, one gate of Levi.", "webster": "And the gates of the city [shall be] after the names of the tribes of Israel: three gates northward; one gate of Reuben, one gate of Judah, one gate of Levi.", "vulgate": "et portae civitatis in nominibus tribuum Israhel portae tres a septentrione porta Ruben una porta Iudae una porta Levi una;", "brenton": "And the gates of the city shall be after the names of the tribes of Israel: three gates northward; the gate of Ruben, one, and the gate of Juda, one, and the gate of Levi, one."}}, {"v": 32, "ref": "48:32", "o": "וְ/אֶל פְּאַ֣ת קָדִ֗ימָ/ה חֲמֵ֤שׁ מֵאוֹת֙ וְ/אַרְבַּ֣עַת אֲלָפִ֔ים וּ/שְׁעָרִ֖ים שְׁלֹשָׁ֑ה וְ/שַׁ֨עַר יוֹסֵ֜ף אֶחָ֗ד שַׁ֤עַר בִּנְיָמִן֙ אֶחָ֔ד שַׁ֥עַר דָּ֖ן אֶחָֽד", "en": {"kjv": "And at the east side four thousand and five hundred: and three gates; and one gate of Joseph, one gate of Benjamin, one gate of Dan.", "web": "At the east side four thousand and five hundred reeds, and three gates: even the gate of Joseph, one; the gate of Benjamin, one; the gate of Dan, one.", "bsb": "On the east side, which will be 4,500 cubits long, there will be three gates: the gate of Joseph, the gate of Benjamin, and the gate of Dan.", "asv": "And at the east side four thousand and five hundred reeds, and three gates: even the gate of Joseph, one; the gate of Benjamin, one; the gate of Dan, one.", "ylt": "And on the east side five hundred, and four thousand, and three gates: the gate of Joseph one, the gate of Benjamin one, the gate of Dan one.", "dra": "And at the east side, four thousand and five hundred: and three gates, the gate of Joseph one, the gate of Benjamin one, the gate of Dan one.", "bbe": "And at the east side, four thousand five hundred by measure, and three doors, one for Joseph, one for Benjamin, one for Dan;", "geneva": "And at the East side fiue hundreth and foure thousande, and three gates, and one gate of Ioseph, one gate of Beiamin, and one gate of Dan.", "wycliffe": "And at the eest coost, fyue hundrid and foure thousynd rehedis, and thre yatis; o yate of Joseph, o yate of Beniamyn, o yate of Dan.", "rotherham": "and on the east side, four thousand and five hundred, with three gates,— even the gate of Joseph, one the gate of Benjamin, one the gate of Dan, one;", "darby": "And at the east side four thousand and five hundred, and three gates: the gate of Joseph, one; the gate of Benjamin, one; the gate of Dan, one.", "twenty": "", "jps": "and at the east side four thousand and five hundred reeds; and three gates: even the gate of Joseph, one; the gate of Benjamin, one; the gate of Dan, one;", "acv": "And at the east side four thousand and five hundred measures, and three gates: even the gate of Joseph, one, the gate of Benjamin, one, the gate of Dan, one.", "anderson": "", "haweis": "", "noyes": "And on the east side shall be four thousand and five hundred [reeds]; and three gates,—one gate of Joseph, one gate of Benjamin, one gate of Dan.", "webster": "And at the east side four thousand and five hundred: and three gates; one gate of Joseph, one gate of Benjamin, one gate of Dan.", "vulgate": "et ad plagam orientalem quingentos et quattuor milia et portae tres porta Ioseph una porta Beniamin una porta Dan una;", "brenton": "And eastward four thousand and five hundred: and three gates; the gate of Joseph, one, and the gate of Benjamin, one, and the gate of Dan, one."}}, {"v": 33, "ref": "48:33", "o": "וּ/פְאַת נֶ֗גְבָּ/ה חֲמֵ֨שׁ מֵא֜וֹת וְ/אַרְבַּ֤עַת אֲלָפִים֙ מִדָּ֔ה וּ/שְׁעָרִ֖ים שְׁלֹשָׁ֑ה שַׁ֣עַר שִׁמְע֞וֹן אֶחָ֗ד שַׁ֤עַר יִשָּׂשכָר֙ אֶחָ֔ד שַׁ֥עַר זְבוּלֻ֖ן אֶחָֽד", "en": {"kjv": "And at the south side four thousand and five hundred measures: and three gates; one gate of Simeon, one gate of Issachar, one gate of Zebulun.", "web": "At the south side four thousand and five hundred reeds by measure, and three gates: the gate of Simeon, one; the gate of Issachar, one; the gate of Zebulun, one.", "bsb": "On the south side, which will be 4,500 cubits long, there will be three gates: the gate of Simeon, the gate of Issachar, and the gate of Zebulun.", "asv": "And at the south side four thousand and five hundred reeds by measure, and three gates: the gate of Simeon, one; the gate of Issachar, one; the gate of Zebulun, one.", "ylt": "And the south side five hundred, and four thousand measures, and three gates: the gate of Simeon one, the gate of Issachar one, the gate of Zebulun one.", "dra": "And at the south side, thou shalt measure four thousand and five hundred: and three gates, the gate of Simeon one, the gate of Issachar one, the gate of Zabulon one.", "bbe": "And at the south side, four thousand five hundred by measure, and three doors, one for Simeon, one for Issachar, one for Zebulun;", "geneva": "And at the South side, fiue hundreth and foure thousande measures, and three portes, one gate of Simeon, one gate of Isshachar, and one gate of Zebulun.", "wycliffe": "And at the south coost thou schalt mete fyue hundrid and foure thousynde rehedis, and thre yatis schulen be of tho; o yate of Symeon, o yate of Isacar, o yate of Zabulon.", "rotherham": "and on the south side, four thousand and five hundred in measure, with three gates,— the gate of Simeon, one the gate of Issachar, one the gate of Zebulun, one;", "darby": "And at the south side four thousand and five hundred [cubits] by measure, and three gates: the gate of Simeon, one; the gate of Issachar, one; the gate of Zebulun, one.", "twenty": "", "jps": "and at the south side four thousand and five hundred reeds by measure; and three gates: the gate of Simeon, one; the gate of Issachar, one; the gate of Zebulun, one;", "acv": "And at the south side four thousand and five hundred measures by measure, and three gates: the gate of Simeon, one, the gate of Issachar, one, the gate of Zebulun, one.", "anderson": "", "haweis": "", "noyes": "And on the south side its measure shall be four thousand five hundred; and three gates,—one gate of Simeon, one gate of Issachar, one gate of Zebulon.", "webster": "And at the south side four thousand and five hundred measures: and three gates; one gate of Simeon, one gate of Issachar, one gate of Zebulun.", "vulgate": "et ad plagam meridianam quingentos et quattuor milia metieris portam Symeonis unam portam Isachar unam portam Zabulon unam;", "brenton": "And southward, four thousand and five hundred by measure: and three gates; the gate of Symeon, one, and the gate of Issachar, one, and the gate of Zabulon, one."}}, {"v": 34, "ref": "48:34", "o": "פְּאַת יָ֗מָּ/ה חֲמֵ֤שׁ מֵאוֹת֙ וְ/אַרְבַּ֣עַת אֲלָפִ֔ים שַֽׁעֲרֵי/הֶ֖ם שְׁלֹשָׁ֑ה שַׁ֣עַר גָּ֞ד אֶחָ֗ד שַׁ֤עַר אָשֵׁר֙ אֶחָ֔ד שַׁ֥עַר נַפְתָּלִ֖י אֶחָֽד", "en": {"kjv": "At the west side four thousand and five hundred, with their three gates; one gate of Gad, one gate of Asher, one gate of Naphtali.", "web": "At the west side four thousand and five hundred reeds, with their three gates: the gate of Gad, one; the gate of Asher, one; the gate of Naphtali, one.", "bsb": "And on the west side, which will be 4,500 cubits long, there will be three gates: the gate of Gad, the gate of Asher, and the gate of Naphtali.", "asv": "At the west side four thousand and five hundred reeds, with their three gates: the gate of Gad, one; the gate of Asher, one; the gate of Naphtali, one.", "ylt": "The west side five hundred, and four thousand, their gates three: the gate of Gad one, the gate of Asher one, the gate of Naphtali one.", "dra": "And at the west side, four thousand and five hundred, and their three gates, the gate of Gad one, the gate of Aser one, the gate of Nephthali one.", "bbe": "At the west side, four thousand five hundred by measure, with their three doors, one for Gad, one for Asher, one for Naphtali.", "geneva": "At the West side, fiue hundreth and foure thousand, with their three gates, one gate of Gad, one gate of Asher, and one gate of Naphtali.", "wycliffe": "And at the west coost, fyue hundrid and foure thousynde of rehedis, thre yatis of tho; o yate of Gad, o yate of Aser, o yate of Neptalym.", "rotherham": "on the west side, four thousand and five hundred, their gates three,—the gate of Gad, one the gate of Asher, one, the gate of Naphtali one.", "darby": "At the west side four thousand and five hundred, [and] their three gates: the gate of Gad, one; the gate of Asher, one; the gate of Naphtali, one.", "twenty": "", "jps": "at the west side four thousand and five hundred reeds, with their three gates: the gate of Gad, one; the gate of Asher, one; the gate of Naphtali, one.", "acv": "At the west side four thousand and five hundred measures, with their three gates: the gate of Gad, one, the gate of Asher, one, the gate of Naphtali, one.", "anderson": "", "haweis": "", "noyes": "On the west side, four thousand and five hundred; and three gates,—one gate of Gad, one gate of Asher, one gate of Naphtali.", "webster": "And the west side four thousand and five hundred, [with] their three gates: one gate of Gad, one gate of Asher, one gate of Naphtali.", "vulgate": "et ad plagam occidentalem quingenti et quattuor milia portae eorum tres porta Gad una porta Aser una porta Nepthalim una;", "brenton": "And westward, four thousand and five hundred by measure: and three gates; the gate of Gad, one, and the gate of Asser, one, and the gate of Nephthalim, one."}}, {"v": 35, "ref": "48:35", "o": "סָבִ֕יב שְׁמֹנָ֥ה עָשָׂ֖ר אָ֑לֶף וְ/שֵׁם הָ/עִ֥יר מִ/יּ֖וֹם יְהוָ֥ה שָֽׁמָּ/ה", "en": {"kjv": "It was round about eighteen thousand measures: and the name of the city from that day shall be, The Lord is there.", "web": "It shall be eighteen thousand reeds around: and the name of the city from that day shall be, Yahweh is there.", "bsb": "The perimeter of the city will be 18,000 cubits, and from that day on the name of the city will be: THE LORD IS THERE.”", "asv": "It shall be eighteen thousand reeds round about: and the name of the city from that day shall be, Jehovah is there.", "ylt": "Round about is eighteen thousand, and the renown of the city is from the day Jehovah is there.'", "dra": "Its circumference was eighteen thousand: and the name of the city from that day, The Lord is there.", "bbe": "It is to be eighteen thousand all round: and the name of the town from that day will be, The Lord is there.", "geneva": "It was rounde about eighteene thousande measures, and the name of the citie from that day shalbe, The Lord is there.", "wycliffe": "Bi cumpas eiytene miles; and the name schal be fro that dai, The Lord there. Amen.", "rotherham": "Round about, eighteen thousand. And the name of the city, from the day of Yahweh shall [continue to] be the name thereof.", "darby": "Round about it was eighteen thousand [cubits]; and the name of the city from that day, Jehovah is there.", "twenty": "", "jps": "It shall be eighteen thousand reeds round about. And the name of the city from that day shall be, HaShem is there.'", "acv": "It shall be eighteen thousand measures round about. And the name of the city from that day shall be, Jehovah is there.", "anderson": "", "haweis": "", "noyes": "Its measure round about was eighteen thousand reeds. And the name of the city from that day shall be Jehovah-is-there.", "webster": "The circuit [was] eighteen thousand [measures]: and the name of the city from [that] day [shall be], The LORD [is] there.", "vulgate": "per circuitum decem et octo milia et nomen civitatis ex illa die Dominus ibidem;", "brenton": "The circumference, eighteen thousand measures: and the name of the city, from the day that it shall be finished, shall be the name thereof."}}]}]};
window.BOOKS=[{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}];
window.ANNOT={"1:28": [{"ref": "1:28", "title": "The Likeness of the Glory of YHWH", "finding": "Ezekiel's inaugural vision climaxes in hu mar'eh d'mut kevod YHWH (הוא מראה דמות כבוד יהוה, 'this was the appearance of the likeness of the glory of YHWH') - a throne of sapphire borne by four living creatures. The Hebrew never uses the word 'merkabah' (chariot); that label was applied later by Jewish tradition (Ben Sira 49:8; Mishnah Hagigah 2:1's ma'aseh merkabah), which grew into an entire mystical discipline built on this one chapter, and which likely shaped the throne-vision imagery of Revelation 4.", "category": "theology", "citation": "Ben Sira 49:8; Mishnah Hagigah 2:1; Revelation 4:2-8", "tier": "STRONG-INFERENCE"}], "1:10": [{"ref": "1:10", "title": "Four Faces, Babylonian Iconography", "finding": "The vision's four living creatures each have p'nei adam (פני אדם, face of a man), p'nei aryeh (פני אריה, face of a lion), p'nei shor (פני שור, face of an ox), and p'nei nesher (פני נשר, face of an eagle) - a composite-creature template that closely matches the lamassu and apkallu guardian figures carved on Babylonian and Assyrian palace walls (bull-man, lion-griffin, eagle-headed genii). Ezekiel, writing as an exile by the Chebar canal in Babylonia, plausibly draws his throne-guardians from the monumental imperial art he lived among.", "category": "pagan", "citation": "Mesopotamian lamassu/apkallu palace-relief iconography", "tier": "STRONG-INFERENCE"}], "36:28": [{"ref": "36:28", "title": "The One 'Anokhi' in Ezekiel", "finding": "God's covenant formula here reads v'anokhi ehyeh lakhem l'elohim (ואנכי אהיה לכם לאלהים, 'and I [anokhi] will be your God') - remarkable because Ezekiel otherwise uses the shorter pronoun ani (אני) almost exclusively (a 1:169 ratio). Our documentary-clock probe found the Pentateuch's P source shares this same near-total ani-over-anokhi profile (1:120), with both P and Ezekiel each having exactly one stray anokhi in a frozen covenant-formula (P's at Genesis 23:4) - the strongest linguistic argument that P is a 6th-century priestly literary stream contemporary with Ezekiel, not a late Persian-era or Hellenistic composition.", "category": "source-critical", "citation": "study-documentary-clock.md, Probe HEB4 (P-Ezekiel pronoun axis); Genesis 23:4", "tier": "STRONG-INFERENCE"}], "37:11": [{"ref": "37:11", "title": "These Bones Are the Whole House of Israel", "finding": "After the dry-bones vision, God supplies its own interpretation: ha-atzamot ha-eleh kol beit Yisra'el hemmah (העצמות האלה כל בית ישראל המה, 'these bones - they are the whole house of Israel'), voicing the exiles' despair 'our bones are dried up, our hope is lost.' In context this is a national-restoration allegory about the exile ending, not individual bodily resurrection - but its vivid bones-to-life language (37:5, 'I will cause ruach/breath to enter you and you shall live') supplied vocabulary later reused for literal resurrection hope in Daniel 12:2 and beyond.", "category": "typology", "citation": "Daniel 12:2; Isaiah 26:19 (resurrection-hope development)", "tier": "STRONG-INFERENCE"}], "38:2": [{"ref": "38:2", "title": "Gog of Magog", "finding": "God directs Ezekiel to prophesy against Gog eretz ha-Magog (גוג ארץ המגוג, 'Gog, land of Magog'), a northern power invading Israel in the last days. Revelation 20:8 lifts the pairing directly into Greek as ton Gog kai ton Magog, transliterating rather than translating both names - an unambiguous, verbatim literary borrowing from Ezekiel's Hebrew/LXX into apocalyptic Christian scripture roughly seven centuries later.", "category": "ot-allusion", "citation": "Revelation 20:8", "tier": "DEMONSTRABLE"}], "28:13": [{"ref": "28:13", "title": "The King of Tyre in Eden", "finding": "Ezekiel's dirge tells the king of Tyre b'Eden gan Elohim hayita (בעדן גן אלהים היית, 'you were in Eden, the garden of God'), calling him at k'ruv (את כרוב, 'you [were] a cherub') draped in precious stones. In its own context this is royal-court poetry about a historical Phoenician king's hubris and fall, not cosmic myth - the 'Satan's primordial fall from heaven' reading is a later theological extension (echoed in Luke 10:18; Revelation 12:9) layered onto the text centuries after Ezekiel wrote it.", "category": "typology", "citation": "Luke 10:18; Revelation 12:9 (the later Satan's-fall reading)", "tier": "SPECULATIVE"}], "28:2": [{"ref": "28:2", "title": "I Am a God", "finding": "The king of Tyre's crime is claiming el ani (אל אני, 'I am a god'), moshav Elohim yashavti ('I sit in the seat of gods') - self-deification language matching a wider ANE royal-ideology topos of god-kings (compare Isaiah 14:13-14's king of Babylon claiming a throne above the stars, and Daniel 4's Nebuchadnezzar). Ezekiel is applying a stock ANE court-poetry taunt - 'you claimed divinity, but you are adam v'lo el (אדם ולא אל, a man and not a god)' - to Tyre specifically, not inventing a new genre.", "category": "pagan", "citation": "Isaiah 14:13-14; Daniel 4", "tier": "STRONG-INFERENCE"}]};